window.BANNANJE_VERSE_MEANINGS = {
  "1.1": "ಧೃತರಾಷ್ಟ್ರಃ ಉವಾಚ- ಧೃತರಾಷ್ಟ್ರ ಕೇಳಿದನು:\n\nಧರ್ಮಕ್ಷೇತ್ರೇ ಕುರುಕ್ಷೇತ್ರೇ ಸಮವೇತಾಃ ಯುಯುತ್ಸವಃ |\n\nಮಾಮಕಾಃ ಪಾಂಡವಾಃ ಚ ಏವ ಕಿಮ್‌ ಅಕುರ್ವತ ಸಂಜಯ -- ಧರ್ಮದ ತಾಣವಾದ ಕುರುಕ್ಷೇತ್ರದಲ್ಲಿ ಯುದ್ಧದ\nಬಯಕೆಯಿಂದ ನೆರೆದ ನನ್ನವರು ಮತ್ತು ಪಾಂಡವರು ಏನು ಮಾಡಿದರು ಸಂಜಯನೇ?\n\nಈ ಹಿಂದೆ ಹೇಳಿದಂತೆ ಕುರುಡ ಧೃತರಾಷ್ಟ್ರನ ಪ್ರಶ್ನೆ 'ಜೀವದ' ಕುರುಡು ಪ್ರಶ್ನೆ ಕೂಡಾ ಹೌದು. ನಾವು ಎಷ್ಟು\nಕುರುಡರು ಎಂದರೆ ನಮಗೆ ಏನೂ ಗೊತ್ತಿಲ್ಲ ಎನ್ನುವ ವಿಷಯ ಕೂಡಾ ನಮಗೆ ಗೊತ್ತಿಲ್ಲ! ಆದ್ದರಿಂದ ಗೀತೆ\nಧೃತರಾಷ್ಟ್ರನ ಪ್ರಶ್ನೆಯಿಂದಲೇ ಆರಂಭವಾಗುತ್ತದೆ.\n\nಕಣ್ಣು ಕಾಣದ ಧೃತರಾಷ್ಟ್ರ ದೂರದರ್ಶನ ಹಾಗೂ ದೂರಶ್ರವಣ ಶಕ್ತಿಯನ್ನು ವ್ಯಾಸರಿಂದ ಪಡೆದ ಸಂಜಯನಲ್ಲಿ\nಹಾಕಿದ ಪ್ರಶ್ನೆಯೇ ಗೀತೆಯ ಮೊದಲ ಶ್ಲೋಕ. ಪರಶುರಾಮನಿಂದ ಸಮಂತಪಂಚಕ (ಸುತ್ತಲೂ ಐದು\nಸರೋವರ) ನಿರ್ಮಿಸಲ್ಪಟ್ಟು ಧರ್ಮಕ್ಷೇತ್ರ ಎನಿಸಿದ್ದ ಈ ಯುದ್ಧ ಭೂಮಿ, ಆನಂತರ 'ಕುರು' ಎನ್ನುವ ರಾಜನ\nಕಾಲದಲ್ಲಿ ಪರಮ ಧಾರ್ಮಿಕಕ್ಷೇತ್ರವಾಗಿ ಕುರುಕ್ಷೇತ್ರವಾಯಿತು. ಇದನ್ನೇ ಇಲ್ಲಿ \"ಧರ್ಮಕ್ಷೇತ್ರೇ ಕುರುಕ್ಷೇತ್ರೇ\"\nಎಂದು ಸಂಬೋಧಿಸಿದ್ದಾರೆ. ನಮ್ಮ ಹೃದಯ-ಧರ್ಮಕ್ಷೇತ್ರ. ಯಾವುದು ಧರ್ಮ, ಯಾವುದು ಅಧರ್ಮ ಎಂದು\nತೀರ್ಮಾನ ಮಾಡುವ ಮನಸ್ಸು(Mind)-ಕುರುಕ್ಷೇತ್ರ(ಕರ್ಮಕ್ಷೇತ್ರ). ಮನಸ್ಸಿನ ಸಂಘರ್ಷಣೆಯೇ ಮಹಾಭಾರತ\nಇಲ್ಲಿ ಕುರುಡ ಧೃತರಾಷ್ಟ್ರ ಸಂಜಯನಲ್ಲಿ ಕೇಳುತ್ತಾನೆ: 'ಹೋರಾಟ ಬಯಸಿ ಎದುರುಬದುರಾದ 'ನನ್ನವರು'\nಮತ್ತು 'ಪಾಂಡವರು' ಏನು ಮಾಡಿದರು?'' ಎಂದು. ಇಲ್ಲಿ 'ನನ್ನವರು ಮತ್ತು. ಪಾಂಡವರು' ಎಂದು\nಸಂಬೋಧಿಸುವುದರ ಮೂಲಕ ಆಳುವ ದೊರೆಯಾಗಿದ್ದ ಧೃತರಾಷ್ಟ್ರ ತನ್ನಲ್ಲಿರುವ ದೌರ್ಬಲ್ಯವನ್ನು\nವ್ಯಕ್ತಪಡಿಸುತ್ತಿರುವುದು ಈ ಶ್ಲೋಕದಲ್ಲಿ ಸ್ಪಷ್ಟವಾಗಿ ಎದ್ದು ಕಾಣುತ್ತದೆ.",
  "1.2": "ಸಂಜಯ ಉವಾಚ- ಸಂಜಯ ಹೇಳುತ್ತಾನೆ:\n\nದೃಷ್ಟ್ವಾ ತು ಪಾಂಡವ ಅನೀಕಮ್‌ ವ್ಯೂಢಮ್‌ ದುರ್ಯೋಧನಃ ತದಾ।\n\nಆಚಾರ್ಯಮ್‌ ಉಪಸಂಗಮ್ಯ ರಾಜಾ ವಚನಮ್‌ ಅಬ್ರವೀತ್‌ -- ಆಗ ದೊರೆಯಾದ ದುರ್ಯೋಧನ ಸಜ್ಜುಗೊಂಡ\nಪಾಂಡವ ಪಡೆಯನ್ನು ಕಂಡು, ಆಚಾರ್ಯರತ್ತ ನಡೆದು ಮಾತನಾಡಿದನು.\n\nಈ ಶ್ಲೋಕವನ್ನು ವಿಶ್ಲೇಷಿಸುವ ಮೊದಲು ಇಲ್ಲಿ ಬಂದಿರುವ 'ಅನೀಕ' ಎನ್ನುವ ಪದದ ಅರ್ಥವನ್ನು ಸ್ವಲ್ಪ\nತಿಳಿದುಕೊಳ್ಳೋಣ. ನಿಮಗೆ ತಿಳಿದಂತೆ ಮಹಾಭಾರತ ಯುದ್ಧದಲ್ಲಿ ಪಾಲ್ಗೊಂಡಿದ್ದು ಹದಿನೆಂಟು ಅಕ್ಷೋಹಿಣಿ\nಸೈನ್ಯ. ಅದರಲ್ಲಿ ಏಳು ಅಕ್ಷೋಹಿಣಿ ಪಾಂಡವರ ಕಡೆ ಹೋರಾಟ ಮಾಡಿದರೆ ಉಳಿದ ಸೈನ್ಯ ಕೌರವನ\nಕಡೆಯದು. ಇಲ್ಲಿ ಅಕ್ಷೋಹಿಣಿ ಎನ್ನುವುದು ಸೇನೆಯ ಅತಿದೊಡ್ಡ ವಿಭಾಗ. ಹಿಂದಿನ ಕಾಲದಲ್ಲಿ ಸೇನೆಯನ್ನು\nಒಂಬತ್ತು ವಿಭಾಗಗಳಾಗಿ ವಿಂಗಡಿಸುತ್ತಿದ್ದರು. ಅವುಗಳೆಂದರೆ:\n\n(೧) ಪತ್ತಿ: ಒಂದು ಆನೆ; ಒಂದು ರಥ; ಮೂರು ಕುದುರೆ ಹಾಗೂ ಐದು ಕಾಲಾಳುಗಳ ಒಂದು ತುಶಡಿ.\n\n(೨) ಸೇನಾಮುಖ: ಮೂರು ಪತ್ತಿ\n\n(೩) ಗುಲ್ಕ: ಮೂರು ಸೇನಾ ಮುಖ\n\n(೪) ಗಣ: ಮೂರು ಗುಲ್ಮ\n\n(೫) ವಾಹಿನಿ : ಮೂರು ಗಣ\n\n(೬) ಪೃತನಾ: ಮೂರು ವಾಹಿನಿ\n\n(೭) ಚಮೂ: ಮೂರು ಪೃತನಾ\n\n(ಲ) ಅನೀಕಿನಿ: ಮೂರು ಚಮೂ\n\n(೯) ಅಕ್ಷೋಹಿಣಿ: ಹತ್ತು ಅನೀಕಿನಿ- ಅಂದರೆ 21870 ಆನೆಗಳು, 21870 ರಥ, 65610 ಕುದುರೆಗಳು, 1,09,350\nಕಾಲಾಳುಗಳು..\n\nಈ ಮೇಲಿನ ಲೆಕ್ಕಾಚಾರದಂತೆ ಒಂದು ಅನೀಕಿನಿ ಎಂದರೆ ಹತ್ತನೇ ಒಂದು ಅಕ್ಷೋಹಿಣಿ. ಅಂದರೆ 2187\nಆನೆಗಳು, 2187 ರಥ, 6561 ಕುದುರೆಗಳು, 1,09,35 ಕಾಲಾಳುಗಳು. ಇದು ಪಾಂಡವ ಸೇನೆಯ ಎಪ್ಪತ್ತನೇ\nಒಂದು ಭಾಗ. ಯುದ್ಧ ಮಾಡುವಾಗ ಎಲ್ಲಾ ಹದಿನೆಂಟು ಅಕ್ಷೋಹಿಣಿ ಒಮ್ಮೆಗೇ ಸೇರಿ ಯುದ್ಧ ಮಾಡುವುದಿಲ್ಲ.\nಒಂದು ತುಕಡಿ ಒಮ್ಮೆಗೆ ಒಂದು ನಿರ್ಧಿಷ್ಟ ವ್ಯೂಹ ರಚಿಸಿ ಹೋರಾಟ ಮಾಡುತ್ತಾರೆ.\n\nವಿಶಿಷ್ಟವಾದ ವಿನ್ಯಾಸದಿಂದ( ವ್ಯೂಢಂ) ಶಿಸ್ತುಬದ್ಧವಾಗಿ ಸಜ್ಜಾಗಿ ನಿಂತ ಪಾಂಡವ ಸೇನೆಯ ಒಂದು 'ಅನೀಕ'\nವನ್ನು ಕಂಡಾಗ ದುರ್ಯೋಧನನ ದುಗುಡ ಹೆಚ್ಚುತ್ತದೆ. ಇದು ಮಾನಸಿಕವಾಗಿ ಆತನಿಗಾಗುತ್ತಿರುವ ಮೊದಲ\nಆಘಾತ. ಈ ಮಾನಸಿಕ ಸ್ಥಿತಿಯಲ್ಲಿ ಆತ ಆಚಾರ್ಯರ ಬಳಿ ಹೋಗುತ್ತಾನೆ. ಇಲ್ಲಿ ಆಚಾರ್ಯ ಅಂದರೆ ಗುರುಗಳಲ್ಲಿ\nಹಿರಿಯರಾದ ದ್ರೋಣಾಚಾರ್ಯರು. ಅವರ ಬಳಿಗೆ ಹೋಗಿ ನಮಸ್ಕರಿಸಿ; ಶಿಷ್ಯನ ರೀತಿ ವರ್ತಿಸದೇ, ತಾನು ರಾಜ\nಎನ್ನುವಂತೆ ಅಹಂಕಾರದಿಂದ ಆಡಬಾರದ ರೀತಿ ಮಾತನಾಡುತ್ತಾನೆ.\n\nಈ ಶ್ಲೋಕದಲ್ಲಿ ಮನಃಶಾಸ್ತ್ರಕ್ಕೆ ಸಂಬಂಧಪಟ್ಟ ವಿಷಯವನ್ನು ಸೂಕ್ಷ್ಮವಾಗಿ ಗಮನಿಸಿ. ಯುದ್ಧ ಭೂಮಿಗೆ \"ತಾನು\nಗೆದ್ದೇ ಗೆಲ್ಲುತ್ತೇನೆ” ಎಂದು ಬಂದಿದ್ದ ದುರ್ಯೋಧನ, ಪಾಂಡವರ ಒಂದು ಅನೀಕವನ್ನು ನೋಡಿದಾಕ್ಷಣ ಮಾನಸಿಕ\nಅಸಮತೋಲನ ಹೊಂದುತ್ತಾನೆ. ಅದರಿಂದ ಆತ ಹೇಗೆ ತಳಮಳಗೊಂಡ ಎನ್ನುವುದನ್ನು ಈ ಶ್ಲೋಕದಲ್ಲಿ\n'ದೃಷ್ಟ್ವಾತು(ಮೇಲಂತೂ)' ಎನ್ನುವಲ್ಲಿ ಒತ್ತಿ ಹೇಳಿದ್ದಾರೆ. ತನ್ನಲ್ಲಿ ಹನ್ನೊಂದು ಅಕ್ಷೋಹಿಣಿ ಸೈನ್ಯ ಇದ್ದಾಗ್ಯೂ,\nಪಾಂಡವರ ಒಂದು ಪುಟ್ಟ ಅನೀಕವನ್ನು ಕಂಡು ಮಾನಸಿಕವಾಗಿ ವಿಪ್ಣವನಾದ ದುರ್ಯೋಧನ, ಆಚಾರ್ಯ\nದ್ರೋಣರಲ್ಲಿ. ಹೋಗಿ ಹೇಗೆ ಅಹಂಕಾರದಿಂದ ಮಾತನಾಡಿದ ಎನ್ನುವುದನ್ನು ಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ\nನೋಡೋಣ.",
  "1.3": "ಪಶ್ಯ ಏತಾಮ್‌ ಪಾಂಡುಪುತ್ರಾಣಾಮ್‌ ಆಚಾರ್ಯ ಮಹತೀಮ್‌ ಚಮೂಮ್‌ |\nವ್ಯೂಢಾಮ್‌ ದ್ರುಪದಪುತ್ರೇಣ ತವ ಶಿಷ್ಯೇಣ ಧೀ-ಮತಾ -- ನೋಡು ಆಚಾರ್ಯ, ಪಾಂಡು ಪುತ್ರರ ಈ ದೊಡ್ಡ\nದಂಡನ್ನು, ನಿನ್ನ ಜಾಣ ಶಿಷ್ಯ ದ್ರುಪದ ಪುತ್ರನಿಂದ ಸಜ್ಜುಗೊಂಡಿದ್ದನ್ನು.\n\nದುರ್ಯೋಧನ ಸೇನಾಧಿಪತಿ ಭೀಷ್ಮರ ಬಳಿ ಹೋಗದೆ, ದ್ರೋಣಾಚಾರ್ಯರ ಬಳಿ ಹೋಗಿ, ಭೀಷ್ಮಾಚಾರ್ಯರಿಗೆ\nಕೇಳುವಂತೆ, ಆಚಾರ್ಯ ದ್ರೋಣರಲ್ಲಿ ನಂಜಿನ ಮಾತನ್ನಾಡುತ್ತಾನೆ. ಇಲ್ಲಿ ದ್ರೋಣರನ್ನು ದುರ್ಯೋಧನ\n\"ಪಾಂಡವರ ಆಚಾರ್ಯ” ಎಂದು ಚುಚ್ಚಿ ಸಂಬೋಧಿಸುತ್ತಾನೆ. “ತನ್ನ ಪ್ರೀತಿಯ ಶಿಷ್ಯರು ಎಂದು ಉದಾರ\nತೋರಬೇಡಿ” ಎನ್ನುವುದು ಆತನ ಈ ಮಾತಿನ ಅರ್ಥ.\n\nಪಾಂಡವರ ಸೇನಾಧಿಪತ್ಯವನ್ನು ದ್ರುಪದ ಪುತ್ರನಾದ ದೃಷ್ಟಧ್ಯುಮ್ನ ವಹಿಸಿರುತ್ತಾನೆ. ದ್ರುಪದ ಮತ್ತು ದ್ರೋಣರು\nಬಾಲ್ಯ ಸ್ನೇಹಿತರು. ಆದರೆ ಕೆಲಕಾಲಾನಂತರ ದ್ರುಪದ ಸಿಂಹಾಸನವೇರುತ್ತಾನೆ. ಆ ಸಮಯದಲ್ಲಿ ಬಡ\nಬ್ರಾಹ್ಮಣನಾದ ದ್ರೋಣ ತನ್ನ ಮಗನಿಗೆ ಹಾಲು ಕುಡಿಸಲು ಒಂದು ಹಸುವನ್ನು ಕೊಡು ಎಂದು ದ್ರುಪದನನ್ನು\nಬಾಲ್ಯದ ಸಲಿಗೆಯಲ್ಲಿ ಕೇಳಿಕೊಂಡು ಬರುತ್ತಾನೆ. ಆದರೆ ದ್ರುಪದ \"ನಿನಗೆ ನನ್ನನ್ನು ಸ್ನೇಹಿತ ಎಂದು ಕರೆಯುವ\nಯೋಗ್ಯತೆ ಇಲ್ಲ, ನಾನು ರಾಜ, ಆದರೆ ನೀನೊಬ್ಬ ಬಡ ಬ್ರಾಹ್ಮಣ. ನನಗೂ ನಿನಗೂ ಎಂತಹ ಸ್ನೇಹ\" ಎಂದು\nಹೇಳಿ ಅಪಮಾನಗೊಳಿಸುತ್ತಾನೆ. ಇದೇ ದ್ವೇಷದಿಂದ ದ್ರೋಣಾಚಾರ್ಯರು ಕೌರವ-ಪಾಂಡವರ ಗುರುವಾಗಿ\nಸೇರಿ, ಅವರ ವಿಧ್ಯಾಭಾಸ ಮುಗಿದ ಮೇಲೆ ಪಾಂಡವರಿಂದ ದ್ರುಪದನನ್ನು ಸೆರೆಹಿಡಿದು, ಆತನ ಅರ್ಧ\nರಾಜ್ಯವನ್ನು ಕಿತ್ತುಕೊಂಡು, ''ಈಗ ನಾನು ನಿನಗೆ ಸಮನಾಗಿದ್ದೇನೆ. ಈಗಲಾದರೂ ನನ್ನನ್ನು ಸ್ನೇಹಿತ ಎಂದು\nಒಪ್ಪಿಕೋ\" ಎನ್ನುತ್ತಾರೆ. ಇದೇ ಸೇಡಿನಿಂದ ದ್ರುಪದ ಒಂದು ಮಹಾಯಾಗವನ್ನು ಮಾಡಿ ದ್ರೋಣನನ್ನು ಕೊಲ್ಲಬಲ್ಲ\nಮಗನನ್ನು ವರವಾಗಿ ಪಡೆದು ಆತನನ್ನು ದ್ರೋಣಾಚಾರ್ಯರಲ್ಲೇ ವಿದ್ಯಾಭ್ಯಾಸ ಮಾಡಿಸಿ, ತನ್ನ ಸೇಡನ್ನು\nತೀರಿಸಿಕೊಳ್ಳಲು ಕಾಯುತ್ತಿರುತ್ತಾನೆ. ಆತನೇ ದೃಷ್ಟ ಧ್ಯುಮ್ನ -ಪಾಂಡವ ಸೇನಾಧಿಪತಿ.\n\nದುರ್ಯೋಧನ ದ್ರೋಣನನ್ನು ಕುರಿತು \"ನಿಮ್ಮ ಶಿಷ್ಯ-ದ್ರುಪದ ಪುತ್ರ, ಅತೀ ಹತ್ತಿರದಲ್ಲಿ, ಶಿಸ್ತುಬದ್ಧವಾಗಿ\nನಿರ್ಮಿಸಿರುವ ಸೇನಾ(ಚಮೂ) ವ್ಯೂಹವನ್ನು ನೋಡಿರಿ” ಎಂದು ಕುಹಕದಿಂದ ನುಡಿಯುತ್ತಾನೆ. ಇಲ್ಲಿ\nಅಂತರಂಗದಲ್ಲಿ ಭಯಗೊಂಡ ದುರ್ಯೋಧನ ಕ್ಷಣಕ್ಷಣಕ್ಕೂ ಮಾಡುತ್ತಿರುವ ತಪ್ಪನ್ನು ಸೂಕ್ಷ್ಮವಾಗಿ ಗಮನಿಸಿ.\nತಾನೇ ರಾಜನಾಗಬೇಕೆಂಬ ಆಸೆ, ಅದರಿಂದ ದ್ವೇಷ, ಅದರಿಂದ ಅಸೂಯೆ, ಅದರಿಂದ ಮಾನಸಿಕ ಸ್ಥಿಮಿತ\nತಪ್ಪುವಿಕೆ, ಅದರಿಂದ ಮಾಡಬಾರದ್ದನ್ನು ಮಾಡುವುದು. ಇದು ನಾವು ದೈನಂದಿನ ಜೀವನದಲ್ಲಿ ಕಾಣುವ\nಅತಿಸಾಮಾನ್ಯ ವಿಚಾರ. ಮನುಷ್ಯ ದಾರಿತಪ್ಪುವ ವಿವಿಧ ಹಂತಗಳಿವು.",
  "1.4": "ಅತ್ರ ಶೂರಾಃ ಮಹಾ ಇಷು ಆಸಾಃ ಭೀಮಾರ್ಜುನ ಸಮಾಃ ಯುಧಿ |\nಯುಯುಧಾನಃ ವಿರಾಟಃ ಚ ದ್ರುಪದಃ ಚ ಮಹಾರಥಃ -- ಇಲ್ಲಿ ಎಲ್ಲರೂ ವೀರರು. ಹಿರಿಯ ಬಿಲ್ಲಾರರು. ಕಾದುವಲ್ಲಿ\nಭೀಮಾರ್ಜುನರಿಗೆ ಸಾಟಿಯಾದವರು. ಸಾತ್ಯಕಿ, ವಿರಾಟ ಮತ್ತು ದ್ರುಪದ ಕೂಡಾ ಹಿರಿಯ ತೇರಾಳು.\n\nಪಾಂಡವರ ಸೈನ್ಯವನ್ನು ನೋಡಿ ಮಾನಸಿಕವಾಗಿ ತಳಮಳಗೊಂಡ ದುರ್ಯೋಧನ, ದ್ರೋಣಾಚಾರ್ಯರ ಬಳಿ\nಹೋಗಿ, ಪಾಂಡವ ಸೇನೆಯ ಬಗ್ಗೆ, ಅಲ್ಲಿರುವ ವೀರರ ಬಗ್ಗೆ ಮಾತನಾಡುತ್ತಾನೆ. ಸಾಮಾನ್ಯವಾಗಿ ನಮಗೆ ಯಾರ\n\nಬಗ್ಗೆ ಭಯವಿದೆಯೋ, ಅವರೇ ಎಲ್ಲಾ ಕಡೆ ಕಂಡಂತೆ ಭಾಸವಾಗುತ್ತದೆ. ಕಂಸನಿಗೆ ಕೃಷ್ಣ ಕಾಣಿಸಿಕೊಂಡಂತೆ. ಇದು\nಮನಃಶಾಸ್ತ್ರ. ಇಲ್ಲಿ ದುರ್ಯೋಧನನಿಗೆ ಭೀಮಾರ್ಜುನರ ಭಯ. ಆ ಭಯದಿಂದಲೇ ಹೇಳುತ್ತಾನೆ \"ಅಲ್ಲಿರುವ\nವೀರರೆಲ್ಲರೂ ಭೀಮಾರ್ಜುನರಿಗೆ ಸಮನಾದವರು. ಅಸಾಧಾರಣ ಬಿಲ್ಲನ್ನು ಹಿಡಿದು ಹೋರಾಡಿ ಗೆಲ್ಲಬಲ್ಲ\nಮಹಾವೀರರು\" ಎಂದು. ವಾಸ್ತವವಾಗಿ ಆಗಿನ ಕಾಲದಲ್ಲಿ ಇದ್ದ ಮಹಾಬಿಲ್ಲು ಎಂದರೆ ಗಾಂಢೀವ. ಗಾಂಢೀವ\nಹಿಡಿದು ಯುದ್ಧ ಮಾಡಬಲ್ಲವರೆಂದರೆ ಅರ್ಜುನ-ಭೀಮ ಮತ್ತು ಶ್ರೀಕೃಷ್ಣ. ಈ ಸಂದರ್ಭದಲ್ಲಿ ದುರ್ಯೋಧನನಿಗೆ\nಪಾಂಡವರ ಪಡೆಯಲ್ಲಿನ ಮಹಾವೀರರೆಲ್ಲರೂ ಭೀಮಾರ್ಜುನರಿಗೆ ಸಮನಾದ ಬಿಲ್ಲಾರರಾಗಿ ಕಾಣುತ್ತಾರೆ. ಇದು\nದುರ್ಯೋಧನನ ಮನುಃಸ್ಥಿತಿಯನ್ನು ಹೇಳುತ್ತದೆ.\n\nಮುಂದೆ ದುರ್ಯೋಧನ ಪಾಂಡವರ ಕಡೆಗಿನ ವೀರರ ಹೆಸರನ್ನು ಒಂದೊಂದಾಗಿ ಹೇಳಲಾರಂಭಿಸುತ್ತಾನೆ.\n“ಸಾತ್ಯಕಿ, ವಿರಾಟ, ದ್ರುಪದರಂತಹ ಮಹಾರಥರು ಪಾಂಡವ ಸೇನೆಯಲ್ಲಿದ್ದಾರೆ” ಎನ್ನುತ್ತಾನೆ. ಇಲ್ಲಿ ಈ ಮೂರು\nಹೆಸರು. ಬರಲು ವಿಶೇಷ ಕಾರಣವಿದೆ. ಈ ಮೂವರೂ ಕೂಡಾ ಕೌರವರ ಕಡೆಗೆ ಬರಬೇಕಾಗಿತ್ತು.\nಜರಾಸಂಧನೊಡನಿದ್ದು, ಕೃಷ್ಣನ ವಿರುದ್ಧ ಹೋರಾಡಿದ ದ್ರುಪದನನ್ನು ಹಿಂದೆ ಪಾಂಡವರು ಬಂಧಿಸಿ, ಅವನ\nಅರ್ಧರಾಜ್ಯವನ್ನು ಕಿತ್ತುಕೊಂಡು ದ್ರೋಣನಿಗೆ ಕೊಟ್ಟ ವಿಷಯ ಈ ಹಿಂದೆ ನೋಡಿದ್ದೇವೆ. ಆದರೆ ಪಾಂಡವರಿಗೆ\nದ್ರೌಪದಿಯನ್ನು ಕೊಟ್ಟು ಸಂಬಂಧ ಬೆಳೆಸಿದ ದ್ರುಪದ-ಪಾಂಡವರ ಪರ ನಿಂತ. ವಿರಾಟ ಈ ಹಿಂದೆ ಕೀಚಕನಿಗೆ\nಹೆದರಿಕೊಂಡು ರಾಜ್ಯಭಾರ ಮಾಡುತ್ತಿದ್ದ. ಕೀಚಕನನ್ನು ಭೀಮ ಕೊಂದಿದ್ದರಿಂದ ವಿರಾಟ ಪಾಂಡವರ\nಪಾಳಯವನ್ನು ಸೇರಿಕೊಂಡ. ಇನ್ನು. ಬಲರಾಮನ ಆಣತಿಯನ್ನು ಮೀರದ ಸಾತ್ಯಕಿ. ಇಲ್ಲಿ ಬಲರಾಮ\n\"ಯುದ್ಧದಲ್ಲಿ ತಾನು ತಲೆ ಹಾಕುವುದಿಲ್ಲ'. ಎಂದು ತೀರ್ಥಯಾತ್ರೆಗೆ ಹೊರಟು ಹೋಗಿರುವುದರಿಂದ ಸಾತ್ಯಕಿ\nಕೂಡಾ ಪಾಂಡವರ ಪರ ನಿಂತ. ಹೀಗೆ ಈ ಪ್ರತಿಯೊಂದು ಹೆಸರನ್ನು ತೆಗೆದು ಹೇಳುತ್ತಿರುವ ದುರ್ಯೋಧನನಿಗೆ\nಅಂತರಂಗದಲ್ಲಿ “ಅಯ್ಯೋ ನನ್ನ ಕಡೆ ಇರಬೇಕಾದ ಈ ಮಹಾರಥರು ಪಾಂಡವರ ಪಕ್ಷದಲ್ಲಿದ್ದಾರಲ್ಲ” ಎನ್ನುವ\nನೋವಿದೆ. ಇದು ದುರ್ಯೋಧನನ ವಿಷಾದ! ಆತ ತನ್ನ ಯುದ್ಧತಂತ್ರವನ್ನು ರೂಪಿಸುವುದನ್ನು ಬಿಟ್ಟು, ಇಲ್ಲಿ ತನ್ನ\nಕಡೆಗೆ ಬರಬೇಕಾಗಿದ್ದವರು ಪಾಂಡವರ ಕಡೆ ಸೇರಿದ್ದಾರಲ್ಲಾ ಎಂದು ವಿಷಾದಿಸುವುದರಲ್ಲಿ ಕಾಲಹರಣ\nಮಾಡುತ್ತಿದ್ದಾನೆ. ಇನ್ನೂ ಅನೇಕ ವೀರರ ಹೆಸರನ್ನು ದುರ್ಯೋಧನ ಪಟ್ಟಿ ಮಾಡುತ್ತಾನೆ.",
  "1.5": "ಧೃಷ್ಟಕೇತುಃ ಚೇಕಿತಾನಃ ಕಾಶಿರಾಜಃ ಚ ವೀರ್ಯವಾನ್ |\nಪುರುಜಿತ್ ಕುಂತಿಭೋಜಃ ಚ ಶೈಬ್ಯಃ ಚ ನರಪುಂಗವಃ -- ಧೃಷ್ಟಕೇತು, ಚೇಕಿತಾನ, ಕಾಶಿರಾಜ, ಕೂಡಾ ಕಡುಗಲಿ. ಪುರುಜಿತನು, ಕುಂತಿಭೋಜನು, ಶೈಬ್ಯ ಕೂಡಾ ಗಂಡುಗಲಿ.\n\nಮೇಲ್ನೋಟಕ್ಕೆ ಈ ಶ್ಲೋಕದಲ್ಲಿ ನಾವು ಆರು ಮಂದಿ ವೀರರ ಹೆಸರನ್ನು ಕಾಣುತ್ತೇವೆ. ಆದರೆ ಇಲ್ಲಿ ನಾವು ನೋಡಬೇಕಾದದ್ದು ಕೇವಲ ಈ ಆರು ವ್ಯಕ್ತಿಗಳನ್ನಲ್ಲ. ಈ ವ್ಯಕ್ತಿಗಳ ಹೆಸರನ್ನು ಹೆಕ್ಕಿ ಹೇಳುತ್ತಿರುವ ದುಯೋರ್ಧನನ ಮನಃಸ್ಥಿತಿಯನ್ನು, ಆತನ ವೇದನೆಯನ್ನು. ಧೃಷ್ಟಕೇತು ಶಿಶುಪಾಲನ ಮಗ — ಶಿಶುಪಾಲನನ್ನು ಕೃಷ್ಣ ಕೊಂದಿದ್ದ; ಈಗ ಆ ಶತ್ರುವಿನ ಮಗ ಪಾಂಡವರ ಪರ! ಚೇಕಿತಾನ ಯಾದವ ವೀರ — ಬಲರಾಮನ ಅನುಪಸ್ಥಿತಿಯಲ್ಲಿ ಪಾಂಡವರ ಪಾಳಯ ಸೇರಿದ. ಕಾಶಿರಾಜ ಭೀಮಸೇನನ ಮಾವ. ಪುರುಜಿತ್ ಮತ್ತು ಕುಂತಿಭೋಜ ಕುಂತೀದೇವಿಯ ದತ್ತು ಸಂಬಂಧಿಗಳು — ಅವರೂ ಪಾಂಡವರ ಪರ. ಶೈಬ್ಯ — ಅವನ ಮಗ ಜಯದ್ರಥನಿಗೆ ಸಹಾಯ ಮಾಡಿದಾಗ ಭೀಮಸೇನನಿಂದ ಕೊಲ್ಲಲ್ಪಟ್ಟ; ಆ ಶೈಬ್ಯನೂ ಪಾಂಡವರ ಪರ ನಿಂತಿದ್ದಾನೆ.",
  "1.6": "ಯುಧಾಮನ್ಯುಃ ಚ ವಿಕ್ರಾಂತ ಉತ್ತಮೌಜಾಃ ಚ ವೀರ್ಯವಾನ್‌ |\nಸೌಭದ್ರಃ ದ್ರೌಪದೇಯಾಃ ಚ ಸರ್ವೇ ಏವ ಮಹಾರಥಾಃ - ಯುಧಾಮನ್ಯುವು ಕೆಚ್ಚೆದೆಯವನು. ಉತ್ತಮೌಜ\nಕೂಡಾ ಕಡುಗಲಿ. ಸುಭದ್ರೆಯ ಮಗ, ದ್ರೌಪದಿಯ ಮಕ್ಕಳು ಎಲ್ಲರೂ ನಿಶ್ಚಯವಾಗಿ ಹಿರಿಯ ತೇರಾಳುಗಳೇ.\n\nಪಾಂಡವ ಸೇನೆಯನ್ನು ಕಂಡು ಅಂತರಂಗದಲ್ಲಿ ಗಾಬರಿಗೊಂಡ ದುರ್ಯೋಧನನು, ಒಂದೇ ಮನೆಯಿಂದ ಬಂದ\nಪ್ರತಿಯೊಬ್ಬ ವ್ಯಕ್ತಿಯ ಬಗ್ಗೆ ಇಲ್ಲಿ ಪ್ರಸ್ತಾಪಿಸುತ್ತಾನೆ. ಯುಧಾಮನ್ಯು ಹಾಗೂ ಉತ್ತಮೌಜ ಇವರು ದ್ರುಪದನ\nಇನ್ನಿಬ್ಬರು ಮಕ್ಕಳು. ಇವರನ್ನು ದುರ್ಯೋಧನ ವೀರ ನೆಡೆಯುಳ್ಳ ವಿಕ್ರಾಂತರು ಎಂದು ಸಂಬೋಧಿಸುತ್ತಾನೆ.\nಇಷ್ಟೇ ಅಲ್ಲ ಆತ ಸುಭದ್ರೆಯ ಮಗ ಅಭಿಮನ್ಯು ಹಾಗೂ ಇನ್ನೂ ಪ್ರಾಯಪ್ರಭುದ್ದರಲ್ಲದ ಸುಮಾರು\nಹದಿಮೂರರಿಂದ ಹದಿನೆಂಟು ಪ್ರಾಯದ ಐದು ಮಂದಿ ದ್ರೌಪದಿಯ ಮಕ್ಕಳನ್ನು ಮಹಾರಥರು. ಎಂದು\nಸಂಬೋಧಿಸುತ್ತಾನೆ!\n\nಇಲ್ಲಿ ಸ್ಪಷ್ಟವಾಗಿ ನಾವು ಕಂಡು ಕೊಳ್ಳಬೇಕಾದ ವಿಷಯವೆಂದರೆ, ಒಮ್ಮೆ ನಾವು ಭಯಕ್ಕೊಳಪಟ್ಟರೆ ನಮಗೆ ಹಗ್ಗ\nಹಾವಿನಂತೆ ಕಾಣಲಾರಂಭಿಸುತ್ತದೆ. ಇಂತಹ ಸಂಧರ್ಭದಲ್ಲಿ ನಮ್ಮಲ್ಲಿರುವ ನಿಜವಾದ ಸಾಮರ್ಥ್ಯ ಕೂಡಾ\nವ್ಯರ್ಥವಾಗುತ್ತದೆ. ತನ್ನಲ್ಲಿ ಹನ್ನೊಂದು ಅಕ್ಷೋಹಿಣಿ ಸೈನ್ಯವಿದ್ದೂ ಕೂಡಾ, ಯುದ್ಧಕ್ಕೆ ಮೊದಲು ತನ್ನ ಸೈನ್ಯವನ್ನು\nಹುರಿದುಂಬಿಸುವುದನ್ನು ಬಿಟ್ಟು, ದುರ್ಯೋಧನ ಪಾಂಡವ ಸೈನ್ಯದಲ್ಲಿನ ವೀರರ ಬಗ್ಗೆ ಮಾತನಾಡುತ್ತಿರುವುದು\nಸ್ಪಷ್ಟವಾಗಿ ಆತನ ಮನಃಸ್ಥಿತಿಯನ್ನು ಸೂಚಿಸುತ್ತದೆ. ಆತ ಇಲ್ಲಿ ಹನ್ನೊಂದು ಮಂದಿ ವೀರರ ಹೆಸರನ್ನು\nಹೇಳಿರುವುದನ್ನು ನಾವು ಗಮನಿಸಬೇಕು(ಸಾತ್ಯಕಿ, ವಿರಾಟ, ದ್ರುಪದ, ಧೃಷ್ಟಕೇತು, ಚೇಕಿತಾನ, ಕಾಶಿರಾಜ,\nಪುರುಜಿತ್‌, ಕುಂತಿಭೋಜ,ಶೈಭ್ಯ, ಯುಧಾಮನ್ಯು ಹಾಗೂ ಉತ್ತಮೌಜ). ತನ್ನಲ್ಲಿ ಹನ್ನೊಂದು ಅಕ್ಷೋಹಿಣಿ\nಸೈನ್ಯವನ್ನು ಪ್ರತಿನಿಧಿಸುವ ವೀರರಿದ್ದರೂ ಕೂಡಾ, ಆತನಿಗೆ ಏಳು ಅಕ್ಷೋಹಿಣಿ ಸೈನ್ಯವಿರುವ ಪಾಂಡವ\nಸೈನ್ಯದಲ್ಲಿ ಹನ್ನೊಂದು ಮಂದಿ ವೀರರು ಎದ್ದು ಕಾಣಲಾರಂಭಿಸುತ್ತಾರೆ! ಭಗವಂತನಿಂದ ದೂರ ನಿಂತ\nಅಧರ್ಮಿಯಾದ ಪ್ರತಿಯೊಬ್ಬರ ಪಾಡು ಇಷ್ಟೇ. ಅವರು ಎಂದೆಂದೂ ಅಂತರಂಗದ ಭಯದಲ್ಲೇ ಬದುಕುತ್ತಾರೆ\nಹಾಗೂ ಆ ಭಯವನ್ನು ಮುಚ್ಚಿಡಲು ಇಲ್ಲ ಸಲ್ಲದ ಮಾತನ್ನಾಡುತ್ತಾರೆ. ಒಬ್ಬ ದುಷ್ಟ ಕೆಟ್ಟದಾಗಿ ಗೌರವವಿಲ್ಲದೆ\nಮಾತನಾಡುತ್ತಿದ್ದಾನೆ ಎಂದರೆ ಆತ ಅಂತರಂಗದಲ್ಲಿ ತುಂಬಾ ಭಯಭೀತನಾಗಿದ್ದಾನೆ ಎಂದರ್ಥ. ಅಂತವರಲ್ಲಿ\nಎಷ್ಟೇ ಶಕ್ತಿ ಇದ್ದರೂ ಕೂಡಾ ಅದು ಎಂದೂ ಅವರ ರಕ್ಷಣೆ ಮಾಡಲಾರದು. ಏಕೆಂದರೆ ಅವರಿಗೆ ತಮ್ಮ ಶಕ್ತಿಯ\nಬಗ್ಗೆ ಆತ್ಮವಿಶ್ವಾಸವಿರುವುದಿಲ್ಲ. ಇದು ಇಲ್ಲಿ ನಾವು ಕಂಡುಕೊಳ್ಳಬೇಕಾದ ಮನಃಶಾಸ್ತ್ರ.",
  "1.7": "ಅಸ್ಮಾಕಮ್‌ ತು ವಿಶಿಷ್ಟಾಃ ಯೇ ತಾನ್‌ ನಿಬೋಧ ದ್ವಿಜೋತ್ತಮ |\n\nನಾಯಕಾಃ ಮಮ ಸೈನ್ಯಸ್ಯ ಸಂಜ್ಞಾ ಅರ್ಥಮ್‌ ತಾನ್‌ ಬ್ರವೀಮಿ ತೇ -- ಓ ದ್ವಿಜೋತ್ತಮಾ, ನಮ್ಮ ಕಡೆಯ\nಹೆಚ್ಚಾಳುಗಳು, ನನ್ನ ಪಡೆಯ ಮುಂದಾಳುಗಳು ಯಾರಿದ್ದಾರೆ. ಅವರ ಬಗೆಗೆ ಕೇಳು. ನಿನ್ನ ಸನ್ನೆಗೆಂದು ಅವರನ್ನು\nಹೆಸರಿಸುತ್ತಿದ್ದೇನೆ.\n\nಒಬ್ಬ ವೀರನಾದವನು ತನ್ನ ಶಕ್ತಿ-ಸಾಮರ್ಥ್ಯ ಕಡಿಮೆ ಇದ್ದರೂ ಕೂಡಾ ಯುದ್ಧಕಾಲದಲ್ಲಿ ಯುಕ್ತಿಯಿಂದ ಕಾರ್ಯ\nನಿರ್ವಹಿಸುತ್ತಾನೆ. ಮುಂದಾಳುವಾದವನು ತನ್ನ ಸೈನ್ಯವನ್ನು, ತನ್ನ ಹಿಂಬಾಲಕರನ್ನು ಹುರಿದುಂಬಿಸುತ್ತಾನೆ.\nತಾವು ಶತ್ರು ಸೈನ್ಯಕ್ಕಿಂತ ಶಕ್ತರು ಎನ್ನುವ ಆತ್ಮವಿಶ್ವಾಸವನ್ನು ತನ್ನ ಸೈನ್ಯದಲ್ಲಿ ತುಂಬುತ್ತಾನೆ. ಆದರೆ ಇಲ್ಲಿ\nದುರ್ಯೋಧನ ತನ್ನ ಸೇನಾಧಿಪತಿ ಭೀಷ್ಮರಲ್ಲಿ ಪರಾಮರ್ಷೆ ಮಾಡುವುದನ್ನು ಬಿಟ್ಟು, ಆಚಾರ್ಯ ದ್ರೋಣರಲ್ಲಿ\nಶತ್ರು ಸೈನ್ಯದ ವೀರರ ಬಗ್ಗೆ ವಿಶಿಷ್ಟವಾಗಿ ಮಾತನಾಡಿ, 'ನಿಮ್ಮ ಸನ್ನೆಗೆಂದು ನಮ್ಮ ಸೈನ್ಯದ ಮುಂದಾಳುಗಳ\nಬಗ್ಗೆ ಹೇಳುತ್ತೇನೆ' ಎನ್ನುತ್ತಾನೆ!",
  "1.8": "ಭವಾನ್‌ ಭೀಷ್ಮಃ ಚ ಕರ್ಣಃ ಚ ಕೃಪಃ ಚ ಸಮಿತಿಂಜಯಃ |\nಅಶ್ವತ್ಥಾಮಾ ವಿಕರ್ಣಃ ಚ ಸೌಮದತ್ತಿಃ ತಥಾ ಏವ ಚ -- ಪೂಜ್ಯನಾದ ನೀನು, ಭೀಷ್ಮ ಮತ್ತು ಕರ್ಣ, ಕೃಪ ಕೂಡಾ\nಗೆಲುಗಾರ. ಅಶ್ವತ್ಥಾಮಾ ಮತ್ತು ವಿಕರ್ಣ; ಸೋಮದತ್ತನ ಮಗ ಭೂರಿಶ್ರವ ಕೂಡಾ.\n\nಪಾಂಡವ ಸೇನೆಯಲ್ಲಿ-ಸೇನಾಧಿಪತಿ, ಹನ್ನೊಂದು ಮಂದಿ ಮಹಾ ವೀರರು ಹಾಗೂ ಪಾಂಡವರ ಆರು ಮಂದಿ\nಮಕ್ಕಳ ವೀರತ್ವವನ್ನು ವಿವರಿಸಿದ ದುರ್ಯೋಧನನಿಗೆ, ತನ್ನ ಕಡೆಯಲ್ಲಿರುವ ವೀರರು ಕಾಣಿಸುವುದೇ ಇಲ್ಲ! ಇಲ್ಲಿ\nಆತ ಕುಹಕವಾಗಿ ತನ್ನ ಕಡೆಯ ಏಳು ಮಂದಿ ವೀರರ ಹೆಸರನ್ನು ಹೇಳುತ್ತಾನೆ. 'ಭವಾನ್‌' ಅಂದರೆ\nತಾವು(ಪಾಂಡವರ ಆಚಾರ್ಯರು ಎನ್ನುವಂತೆ 1); ಯುದ್ಧಕ್ಕೆ ಮೊದಲು ಧರ್ಮರಾಯನಿಗೆ ಜಯವಾಗಲಿ ಎಂದು\nಆಶೀರ್ವಾದ ಮಾಡಿದ ಭೀಷ್ಮಾಚಾರ್ಯ! ; “ಭೀಷ್ಮ ಯುದ್ಧಭೂಮಿಯಲ್ಲಿ ಇರುವ ತನಕ ತಾನು ಹೋರಾಟ\nಮಾಡುವುದಿಲ್ಲ' ಎಂದು ಶಪತಮಾಡಿ ಕುಳಿತ ಕರ್ಣ; ವೇದ ಪಾರಾಂಗತ ಆಚಾರ್ಯ ಕೃಪಾ; ವಿಕ್ಷಿಪ್ತ ಮನಸ್ಸಿನ\nಅಶ್ವತ್ಥಾಮ; ದ್ರೌಪದಿಯ ಮಾನಭಂಗವನ್ನು ಖಂಡಿಸಿ ಅದರಿಂದ ಲಾಭ ಪಡೆಯಲೆತ್ನಿಸಿದ ವಿಕರ್ಣ;\nದಾಕ್ಷಿಣ್ಯಕ್ಕಾಗಿ ಬಂದ ಭೀಷ್ಮಾಚಾರ್ಯರ ತಂದೆ-ಶಂತನುವಿನ ಅಣ್ಣನ ಮಗ-ಸೋಮದತ್ತನ ಮಗ ಭೂರಿಶ್ರವ!\nಈ ರೀತಿ ತನ್ನ ಕಡೆಯ ಏಳು ಮಂದಿ ವೀರರ ಹೆಸರನ್ನು ಕುಹಕವಾಗಿ ದುರ್ಯೋಧನ ಭೀಷ್ಮಾಚಾರ್ಯರಿಗೆ\nಕೇಳಿಸುವಂತೆ ದ್ರೋಣಾಚಾರ್ಯರಲ್ಲಿ ಹೇಳುತ್ತಾನೆ.\n\nಇಲ್ಲಿ ನಾವು ವಿವರವಾಗಿ ನೋಡಿದರೆ ಕೌರವನ ಕಡೆಯಲ್ಲಿ ಹನ್ನೊಂದು ಅಕ್ಷೋಹಿಣಿ ಸೈನ್ಯವನ್ನು ಮುನ್ನೆಡೆಸಬಲ್ಲ\nವೀರರಿದ್ದರು. ಆತನ ತೊಂಬತ್ತೊಂಬತ್ತು ಮಂದಿ ತಮ್ಮಂದಿರರಿದ್ದರು. ಶಲ್ಯ ಭಗದತ್ತರಂತಹ ವೀರಾಧಿವೀರರು\nದುರ್ಯೋಧನನ ಕಡೆಗಿದ್ದರು. ಆದರೆ ಪಾಂಡವರ ಸೈನ್ಯವನ್ನು ನೋಡಿ ಭಯಗೊಂಡು, ಇದನ್ನೆಲ್ಲವನ್ನು ಮರೆತ\nದುರ್ಯೋಧನ, ತನ್ನ ಕಡೆ ಇರುವ ಮಹಾವೀರರ ಬಗೆಗೆ ಕೇವಲವಾಗಿ ಮಾತನಾಡುತ್ತಾನೆ! ಇಲ್ಲಿ\nಮಾನಸಿಕವಾಗಿ ದುರ್ಯೋಧನ ಎಷ್ಟೊಂದು ವಿಚಲಿತನಾಗಿದ್ದ ಎನ್ನುವುದು ನಮಗೆ ಸ್ಪಷ್ಟವಾಗಿ ಕಾಣುತ್ತದೆ.\nಯುದ್ಧ ಪರಿಣಾಮದ ಬಗ್ಗೆ ಯೋಚಿಸುತ್ತಾ, ಆತ ತನ್ನ ಕರ್ತವ್ಯವನ್ನೇ ಮರೆತಿದ್ದ!",
  "1.9": "ಅನ್ಯೇ ಚ ಬಹವಃ ಶೂರಾಃ ಮತ್‌ ಅರ್ಥೇ ತ್ಯಕ್ತ ಜೀವಿತಾಃ।\nನಾನಾ ಶಸ್ತ್ರ ಪ್ರಹರಣಾಃ ಸರ್ವೇ ಯುದ್ಧ ವಿಶಾರದಾಃ -- 'ಇನ್ನೂ ಬಹಳ ಮಂದಿ ವೀರರಿದ್ದಾರೆ. ನನಗಾಗಿ ಬದುಕು\nತೆರಲು ಬಂದವರು. ಬಗೆಬಗೆಯ ಆಯುಧಗಳಿಂದ ಹೋರಾಡಬಲ್ಲವರು. ಎಲ್ಲರೂ ಕಾಳಗದಲ್ಲಿ ಪಳಗಿದವರು.\n\nಮೇಲ್ನೋಟಕ್ಕೆ ಈ ಶ್ಲೋಕವನ್ನು ನೋಡಿದರೆ ನಮಗೆ ದುರ್ಯೋಧನ ತನ್ನ ಕಡೆಯ ವೀರರ ಬಗ್ಗೆ\nಹೇಳುತ್ತಿರುವಂತೆ ಕಂಡರೂ ಕೂಡಾ, ಇಲ್ಲಿ ಆತ ಹೇಳುತ್ತಿರುವ ವಿಷಯವೇ ಬೇರೆ. ಆತ ಈ ಮಾತನ್ನು\nದ್ರೋಣರಲ್ಲಿ ಹೇಳುತ್ತಿದ್ದಾನೆ, ಹಾಗೂ ಆತ ತನ್ನ ಮಾತನ್ನು ಆರಂಭಿಸಿದ್ದು \"ಪಾಂಡವರ ಆಚಾರ್ಯರೇ\" ಎಂದು.\nಇಲ್ಲಿ ಆತ- ನಮ್ಮ ಕಡೆ ಅನೇಕ ಶೂರರಿದ್ದಾರೆ, 'ಎಲ್ಲರೂ ತಮ್ಮ ಪ್ರಾಣ ಕೊಡಲು ಬಂದವರು' ಎಂದು\nಕುಹಕದಿಂದ ಹೇಳುತ್ತಿದ್ದಾನೆ. ಅವರೆಲ್ಲರೂ ವಿವಿಧ ಶಸ್ತ್ರಗಳನ್ನು ಪ್ರಯೋಗಿಸಬಲ್ಲರು ಎನ್ನುವ ದುರ್ಯೋಧನ,\nತನ್ನ ಪಾಲಿಗೆ ಯಾರೂ ಇಲ್ಲ ಎನ್ನುವ ಭಾವನೆಯನ್ನು ವ್ಯಕ್ತಪಡಿಸುತ್ತಾನೆ.",
  "1.10": "ಅಪರ್ಯಾಪ್ತಮ್‌ ತತ್‌ ಅಸ್ಮಾಕಮ್‌ ಬಲಮ್‌ ಭೀಷ್ಮ ಅಭಿರಕ್ಷಿತಮ್‌ ।\nಪರ್ಯಾಪ್ತಮ್‌ ತು ಇದಮ್‌ ಏತೇಷಾಮ್‌ ಬಲಮ್‌ ಭೀಮ ಅಭಿರಕ್ಷಿತಮ್‌ -- ಭೀಷ್ಮಾಚಾರ್ಯರ ಕಣ್ಗಾಪಿನ ಆ ನಮ್ಮ ಸೇನೆಯ ಸಜ್ಜು ಸಾಲದು. ಭೀಮನ ಕಣ್ಗಾಪಿನ ಇವರ ಈ ಸೇನೆಯೋ ಸಾಕಷ್ಟು ಸಿದ್ಧಗೊಂಡಿದೆ.\n\nಇಲ್ಲಿ ದುರ್ಯೋಧನನ ಮಾತಿನ ಪರ್ಯಾವಸಾನ(Conclusion)ವಿದೆ. ಆತ ಹೇಳುತ್ತಾನೆ: “ಆ ನಮ್ಮ\nಸೈನ್ಯವಿದೆಯಲ್ಲ, ಪಾಂಡವ ಪಕ್ಷಪಾತಿ ಭೀಷ್ಮಾಚಾರ್ಯರ ಮುಂದಾಳತ್ವದಲ್ಲಿನ ಆ ನಮ್ಮ ಸೈನ್ಯ, ಅದು\nಭೀಮನ ಕಣ್ಣಾಪಿನ ಈ ಸೈನ್ಯದ ಮುಂದೆ ಸಜ್ಜಾಗಿರುವುದು ಸಾಲದು” ಎಂದು. ಇಲ್ಲಿ ಸೂಕ್ಷ್ಮವಾಗಿ ನೋಡಿದರೆ\nಭೀಷ್ಮಾಚಾರ್ಯರು ಕೌರವ ಸೇನಾಧಿಪತಿ. ಆದರೆ ಭೀಮ ಪಾಂಡವ ಸೇನಾಧಿಪತಿ ಅಲ್ಲ. ದುರ್ಯೋಧನನಿಗೆ\nಭೀಮನ ಮೇಲೆ ದ್ವೇಷವಿದೆ ಹಾಗೂ ಭಯವಿದೆ. ಆ ಕಾರಣದಿಂದ ಆತ ಭೀಮನ ಕಣ್ಗಾಪಿನ ಪಾಂಡವ ಸೇನೆ\nಎಂದು ಸಂಬೋಧಿಸುತ್ತಾನೆ. ಇನ್ನೂ ಸೂಕ್ಷ್ಮವಾಗಿ ನೋಡಿದರೆ- ದುರ್ಯೋಧನ ಯುದ್ಧ ಭೂಮಿಯಲ್ಲಿ ತನ್ನ\nಸೇನೆಯ ಮುಂಚೂಣಿಯಲ್ಲಿ ನಿಂತಿದ್ದಾನೆ. ಪಾಂಡವ ಸೇನೆ ಆತನಿಂದ ದೂರದಲ್ಲಿದೆ. ಆದರೆ ಮಾತನಾಡುವಾಗ\nಆತ \"ಈ ಪಾಂಡವ ಸೇನೆ\" ಹಾಗೂ \"ಆ ನಮ್ಮ ಸೇನೆ” ಎಂದು ಸಂಬೋಧಿಸುತ್ತಾನೆ. ಪಾಂಡವ ಸೇನೆ\nಈಗಾಗಲೇ ತನ್ನ ಹತ್ತಿರ ಬಂದು ನಿಂತಿದೆ ಹಾಗೂ ತನ್ನ ಸೇನೆ ತನ್ನಿಂದ ಬಲು ದೂರದಲ್ಲಿದೆ ಎನ್ನುವಂತೆ ಆತ\nಮಾತನಾಡುತ್ತಿದ್ದಾನೆ.",
  "1.11": "ಅಯನೇಷು ಚ ಸರ್ವೇಷು ಯಥಾ ಭಾಗಮ್‌ ಅವಸ್ಥಿತಾಃ |\nಭೀಷ್ಮಮ್‌ ಏವ ಅಭಿರಕ್ಷಂತು ಭವಂತಃ ಸರ್ವೇ ಏವ ಹಿ -- ಆಯಕಟ್ಟಿನ ಎಲ್ಲೆಡೆಗಳಲ್ಲೂ ತಕ್ಕಂತೆ ಹಂಚಿಕೊಂಡು,\nಕಾವಲು ನಿಂತು-ನೀವೆಲ್ಲರೂ ಭೀಷ್ಮನನ್ನೇ ಕಾಯುತ್ತಿರಬೇಕು.\n\n“ಆಯಕಟ್ಟಿನ ಎಲ್ಲೆಡೆಗಳಲ್ಲೂ ತಕ್ಕಂತೆ ಹಂಚಿಕೊಂಡು ಕಾವಲು ನಿಂತು ನೀವೆಲ್ಲರೂ ಭೀಷ್ಮರನ್ನು\nಕಾಯುತ್ತಿರಬೇಕು” ಎಂದು ದುರ್ಯೋಧನ ದ್ರೋಣರನ್ನುದ್ದೇಶಿಸಿ ಮಾತನಾಡುತ್ತಾನೆ. ಇಲ್ಲಿ \"ಸ್ವಲ್ಪ ನಮ್ಮ\nಮುದುಕ ಸೇನಾಧಿಪತಿ ಭೀಷ್ಮಾಚಾರ್ಯರನ್ನು ನೋಡಿಕೊಳ್ಳಿ” ಎನ್ನುವಂತಿದೆ ಆತನ ಮಾತು. ಆತನಿಗೆ ತನ್ನ\nಸೇನಾಧಿಪತಿಯ ಮೇಲೇ ನಂಬಿಕೆ ಇಲ್ಲ!\n\nಈ ಮಾತನ್ನು ಕೇಳಿ ಭೀಷ್ಮಾಚಾರ್ಯರಿಗೆ ಅದೆಷ್ಟು ನೋವಾಗಿರಬೇಕು. ತನ್ನ ಆತ್ಮಸಾಕ್ಷಿಗೆ ವಿರುದ್ಧವಾಗಿ, ತಾನು\nಹುಟ್ಟಿಬಂದ ಮನೆತನದ ರಾಜಾಜ್ಞೆಗೆ ಬದ್ಧನಾಗಿ, ತನ್ನ ಅಂತರಂಗದ ಇಚ್ಛೆಗೆ ವಿರುದ್ಧವಾಗಿ, ತಾನು ಪ್ರೀತಿಸಿದ\nತನ್ನ ಮಮ್ಮಕ್ಕಳ ವಿರುದ್ಧ ಹೋರಾಟಕ್ಕೆ ಪ್ರಾಮಾಣಿಕವಾಗಿ ನಿಂತಾಗ, ಭರವಸೆ. ಕಳೆದುಕೊಂಡು\nಮಾತನಾಡುತ್ತಿರುವ ದುರ್ಯೋಧನನ ಕುಹಕ ನುಡಿ ಅವರಿಗೆ ಎಷ್ಟೊಂದು ನೋವನ್ನುಂಟುಮಾಡಿರಬಹುದು.\nಇದನ್ನು ನಾವು ಊಹಿಸುವುದೂ ಕಷ್ಟ. ಈ ಮಾತನ್ನು ಕೇಳಿಸಿಕೊಂಡ ಭೀಷ್ಮಾಚಾರ್ಯರು ಏನು ಮಾಡಿದರು\nಎನ್ನುವುದನ್ನು ಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ನೋಡೋಣ.",
  "1.12": "ತಸ್ಯ ಸಂಜನಯನ್‌ ಹರ್ಷಮ್‌ ಕುರುವೃದ್ಧಃ ಪಿತಾಮಹಃ |\nಸಿಂಹನಾದಮ್‌ ವಿನದ್ಯ ಉಚ್ಚೆಃ ಶಂಖಮ್‌ ದಧ್ಮೌ ಪ್ರತಾಪವಾನ್‌ -- ಅವನಿಗೆ ಸಂತಸಬರಿಸಲೆಂದು ಕುರುಗಳ\nಹಿರಿಯಜ್ಜನಾದ ಆ ಎದೆಗಾರ ಭೀಷ್ಮ, ಗಟ್ಟಿಯಾದ ಸಿಂಹನಾದ ಗೈದು ಶಂಖವನ್ನು ಊದಿದರು.\n\nಯುದ್ಧ ಪೂರ್ವದಲ್ಲಿ ಭರವಸೆಯನ್ನು ಕಳೆದುಕೊಂಡು ವಿಷಾದದಿಂದ ಮಾತನಾಡುತ್ತಿರುವ ದುರ್ಯೋಧನನ\nಭರವಸೆ ಹೆಚ್ಚಿಸಲು, ಆತನಿಗೆ ಆತ್ಮ ವಿಶ್ವಾಸವನ್ನು ತುಂಬಲು, ಕುರುವಂಶದ ಅತ್ಯಂತ ಹಿರಿಯ ಪ್ರತಾಪಶಾಲಿ\nವಯೋವೃದ್ಧ ಭೀಷ್ಮಾಚಾರ್ಯರು ಸಿಂಹನಾದಗೈದು, ತನ್ನ ಕರ್ತವ್ಯಕ್ಕೆ ತಕ್ಕಂತೆ ಶಂಖವನ್ನೂದಿದರು.\n\nಶಂಖ ಬಹಳ ದೊಡ್ಡ ದುಷ್ಟ ಸಂಹಾರಕ ಶಕ್ತಿ. ಹಿಂದಿನ ಕಾಲದಲ್ಲಿ ಬೆಳಿಗ್ಗೆ ಮತ್ತು ಸಂಜೆ ತಪ್ಪದೇ ಮನೆಯ ಮೂಲೆ-\nಮೂಲೆಯಿಂದ ಅಷ್ಟ ದಿಕ್ಕುಗಳಿಗೂ ಕೇಳುವಂತೆ ಶಂಖನಾದ ಮಾಡುತ್ತಿದ್ದರು. ಇದಕ್ಕೆ ಕಾರಣ ಶಂಖ\nನಾದದಲ್ಲಿರುವ ದುಷ್ಟಶಕ್ತಿಯ ಎದೆಯೊಡೆಯುವ ಸಾಮರ್ಥ್ಯ. ಶಂಖದ ನಾದ ಎಲ್ಲಿಯವರೆಗೆ ಕೇಳಿಸುತ್ತದೋ,\nಅಲ್ಲಿಯ ತನಕ ಯಾವ ದುಷ್ಟ ಶಕ್ತಿಗಳೂ ಸುಳಿಯಲಾರವು. ಮೃತ್ಯುವಿನ ತಾಂಡವವಾದ ರಣರಂಗದಲ್ಲಿ ಆಸುರೀ\nಶಕ್ತಿಯ ಪ್ರಭಾವ ಇರಬಾರದು ಎನ್ನುವುದಕ್ಕಾಗಿ, ಯುದ್ಧಕ್ಕೆ ತಮ್ಮವರನ್ನು ಸಿದ್ಧಗೊಳಿಸುವುದಕ್ಕಾಗಿ ಮತ್ತು\n\nಶತ್ರುಗಳಿಗೆ ತಾವು. ಸಿದ್ಧ ಎನ್ನುವ ಸಂಕೇತ ಕೊಡಲು ಹಿಂದೆ ಶಂಖವನ್ನು ಬಳಸುತ್ತಿದ್ದರು. ಇಲ್ಲಿ\nಭೀಷ್ಮಾಚಾರ್ಯರು ಶಂಖನಾದದಿಂದ ತಮ್ಮ ಸಿದ್ದತೆಯ ಸಂಕೇತವನ್ನು ಕೌರವ ಸೈನ್ಯಕ್ಕೂ ಹಾಗೂ ಪಾಂಡವ\nಸೈನ್ಯಕ್ಕೂ ರವಾನಿಸಿದ್ದಾರೆ.",
  "1.13": "ತತಃ ಶಂಖಾಃ ಚ ಭೇರ್ಯಃ ಚ ಪಣವ ಅನಕ ಗೋಮುಖಾಃ |\nಸಹಸಾ ಏವ ಅಭ್ಯಹನ್ಯಂತ ಸಃ ಶಬ್ದಃ ತುಮುಲಃ ಅಭವತ್‌ -- ಆ ಬಳಿಕ ಶಂಖಗಳು, ನಗಾರಿಗಳು, ತಮಟೆ -\nಡೋಲು- ಗೋಮುಖಗಳು (ಕಹಳೆ) ಒಮ್ಮೆಲೇ ಬಾರಿಸಲ್ಪಟ್ಟವು. ಆ ಸದ್ದು ಕಿವಿಗಡಚಿಕ್ಕುವ ಗದ್ದಲವಾಯಿತು.\n\nಪ್ರಧಾನ ಸೇನಾಧಿಪತಿಯಾದ ಭೀಷ್ಮಾಚಾರ್ಯರು ಶಂಖನಾದ ಮಾಡಿದ ಬಳಿಕ, ಕೌರವ ಸೈನ್ಯದಿಂದ\nಶಂಖಗಳು, ನಗಾರಿ-ಡೋಲು-ಗೋಮುಖಗಳು-ಒಮ್ಮೆಲೇ ಬಾರಿಸಲ್ಪ ಟ್ಚವು. ಆ ಸದ್ದು ಕಿವಿಗಡಚಿಕ್ಕುವ\nಗದ್ದಲವಾಯಿತು. ಇಲ್ಲಿ ದುರ್ಯೋಧನಾಗಲೀ ಆತನ ತಮ್ಮಂದಿರರಾಗಲೀ ಶಂಖನಾದ ಮಾಡಲಿಲ್ಲ. ಬದಲಾಗಿ\nಸೇನಾಧಿಪತಿಯಿಂದ ಶಂಖ ನಾದವಾಯಿತು. ಅದರ ಹಿಂದೆ ಸೈನ್ಯದ ಮುಖಂಡರಿಂದ ಮತ್ತು ಸೈನಿಕರಿಂದ\nಶಂಖನಾದವಾಯಿತು. ಈ ರೀತಿ ವ್ಯವಸ್ಥಿತ ರೀತಿಯಲ್ಲಿಲ್ಲದ ನಾದ ಗದ್ದಲದಂತೆ ಭಾಸವಾಗುತ್ತಿತ್ತು. ಇಲ್ಲಿ\nದುರ್ಯೋಧನ ತನ್ನಲ್ಲಿರುವ ಶಕ್ತಿಯನ್ನು ವ್ಯವಸ್ಥಿತವಾಗಿ ರೂಪಿಸಿರಲಿಲ್ಲ ಎನ್ನುವುದು ಸ್ಪಷ್ಟವಾಗಿ ಎದ್ದು ಕಾಣುತ್ತದೆ.\nನಮ್ಮಲ್ಲಿ. ಎಷ್ಟೇ ಯುಕ್ತಿ ಸಾಧನವಿರಲಿ, ಎಲ್ಲಿಯ ತನಕ ನಮಗೆ ಆ ಸಾಧನವನ್ನು\nನಿಯಮಬದ್ಧವಾಗಿ ಉಪಯೋಗಿಸಿಕೊಳ್ಳಲು ಬರುವುದಿಲ್ಲವೋ, ಅಲ್ಲಿಯ ತನಕ ಆ ಸಾಧನ ಇದ್ದೂ ವ್ಯರ್ಥ.\nಸಾಧನವನ್ನು ಕೈಯಲ್ಲಿಟ್ಟುಕೊಂಡು. ಅಧಿಕಾರದ ಆಸೆಯಿಂದ ಮನಃಸ್ಥಿತಿ. ಕಳೆದುಕೊಳ್ಳುವ\nಮುಂದಾಳು(Leader) ಎಂದೂ ಯಶವನ್ನು ಕಾಣಲಾರ.",
  "1.14": "ತತಃ -- ಆ ಬಳಿಕ,\nಶ್ವೇತೈಃ ಹಯೈಃ ಯುಕ್ತೇ -- ಬಿಳಿಯ ಕುದುರೆಗಳಿಂದ ಸಜ್ಜುಗೊಂಡ,\nಮಹತಿ ಸ್ಯಂದನೇ ಸ್ಥಿತೌ -- ಹಿರಿಯ ರಥದಲ್ಲಿ ಕುಳಿತ,\nಮಾಧವಃ ಪಾಂಡವಃ ಚ ಏವ -- ಶ್ರೀಕೃಷ್ಣ ಮತ್ತು ಅರ್ಜುನರು,\nದಿವ್ಯೌ ಶಂಖೌ ಪ್ರದಧ್ಮತುಃ -- ದಿವ್ಯವಾದ ಶಂಖಗಳನ್ನು ಊದಿದರು.\n\nಕೌರವ ಸೇನೆಯ ಶಂಖ ನಗಾರಿ ಗದ್ದಲದ ನಂತರ ನಾಲ್ಕು ಬಿಳಿ ಕುದುರೆಗಳಿಂದ ಸಜ್ಜುಗೊಂಡ, ಅಲ್ಲಿ ಇರುವ ರಥಗಳಲ್ಲೇ ಅತಿ ದೊಡ್ಡ ರಥದಲ್ಲಿ ಕುಳಿತ ಶ್ರೀಕೃಷ್ಣ ಮತ್ತು ಅರ್ಜುನರು, ತಮ್ಮ ದಿವ್ಯ ಶಂಖನಾದವನ್ನು ಮಾಡುತ್ತಾರೆ.(ಮೊದಲು ಶ್ರೀಕೃಷ್ಣ ಆ ನಂತರ ಅರ್ಜುನ).\n\nಈ ಶ್ಲೋಕದಲ್ಲಿ ಮಾಧವ ಮತ್ತು ಪಾಂಡವ ಎನ್ನುವ ಎರಡು ವಿಶೇಷಣ ಬಳಕೆಯಾಗಿದೆ. ಇಲ್ಲಿ ಭಗವಂತನನ್ನು ಮಾಧವಃ ಎಂದು ಸಂಬೋಧಿಸಿದ್ದಾರೆ. 'ಮಾ' ಅಂದರೆ ಮಾತೆ ಲಕ್ಷ್ಮಿ. ಆದ್ದರಿಂದ ಮಾಧವ ಅಂದರೆ ಲಕ್ಷ್ಮೀಪತಿ ಭಗವಂತ-ಶ್ರಿ ಮನ್ನಾ ರಾಯಣ . ಇನ್ನು 'ಮಾ' ಅಂದರೆ ಜ್ಞಾನ ಕೂಡಾ ಹೌದು. ಭಗವಂತ ಜ್ಞಾನದ ಒಡೆಯ. ಆದ್ದರಿಂದ ಆತ ಮಾಧವ. ಶ್ರೀಕೃಷ್ಣ-ಅವತಾರದಲ್ಲಿ ಮಧುವಂಶದಲ್ಲಿ ಹುಟ್ಟಿ ಬಂದದ್ದರಿಂದ ಆತನನ್ನು ಮಾಧವ ಎಂದು ಕರೆಯುತ್ತಾರೆ. ವೇದದಲ್ಲಿ ಮಾತೃ ಎನ್ನುವ ಪದವನ್ನು ಮಾತು ಅಥವಾ ವಾಜ್ಮಯ ಎನ್ನುವ ಅರ್ಥದಲ್ಲಿ ಉಪಯೋಗಿಸಿದ್ದಾರೆ. ಏಳು ಮಹಾನ್ ಗ್ರಂಥಗಳಾದ ಋಗ್ವೇದ, ಯಜುರ್ವೇದ, ಸಾಮವೇದ, ಅಥರ್ವವೇದ, ರಾಮಾಯಣ, ಮಹಾಭಾರತ ಹಾಗೂ ಪುರಾಣಗಳನ್ನು ಮಾತೃ ಎನ್ನುತ್ತಾರೆ.ಆದ್ದರಿಂದ ಸಮಸ್ತ ವೈದಿಕ ವಾಜ್ಮಯ ಪ್ರತಿಪಾದನಾದ ಭಗವಂತ ಮಾಧವ.\n\nಇಲ್ಲಿ ಅರ್ಜುನನನ್ನು 'ಪಾಂಡವ' ಎಂದು ಸಂಬೋಧಿಸಿದ್ದಾರೆ. ಅರ್ಜುನ ಕುಂತಿಯ ಮೂರು ಮಂದಿ ಮಕ್ಕಳಲ್ಲಿ ಕೊನೆಯವನು. ಸಾಮಾನ್ಯವಾಗಿ ಯಾವಾಗಲೂ ಕೊನೆಯ ಮಗನ ಮೇಲೆ ಪ್ರೀತಿ ಹೆಚ್ಚು. ಅದಕ್ಕಾಗಿ ಆತನನ್ನು ಪಾರ್ಥ, ಕೌಂತೇಯ, ಪಾಂಡವ ಎಂದು ಕರೆಯುತ್ತಿದ್ದರು. ಅರ್ಜುನನಲ್ಲಿ ಭಗವಂತನ ವಿಶೇಷ ಸನ್ನಿಧಾನವಿತ್ತು. ಆತ ನಾರಾಯಣನ ಜೊತೆಗಾರನಾದ 'ನರನ' ರೂಪ ಕೂಡಾ ಹೌದು.\n\nನಮ್ಮ ದೇಹ ಕೂಡಾ ಒಂದು ರಥ. ಅಂತಹ ರಥದಲ್ಲಿ ಜೀವನನ್ನು ನಡೆಸುವ ಭಗವಂತನ ಸನ್ನಿಧಾನವಿದೆ.  ನಾಲ್ಕು ಕುದುರೆಗಳೆಂದರೆ  ನಾಲ್ಕು ವೇದಗಳು.  ಬಿಳಿ ಬಣ್ಣ ಸತ್ವಗುಣದ ಸಂಕೇತ",
  "1.15": "ಪಾಂಚಜನ್ಯಮ್‌ ಹೃಷೀಕೇಶಃ ದೇವದತ್ತಮ್‌ ಧನಂಜಯಃ |\nಪೌಂಡ್ರಮ್‌ ದಧ್ಮೌ ಮಹಾಶಂಖಮ್‌ ಭೀಮಕರ್ಮಾ ವೃಕೋದರಃ - ಶ್ರೀಕೃಷ್ಣನು ಪಾಂಚಜನ್ಯವನ್ನು,\nಅರ್ಜುನನು ದೇವದತ್ತವನ್ನು, ಪೌಂಡ್ರ ಎನ್ನುವ ಮಹಾ ಶಂಖವನ್ನು ಭೀಮನು ಊದಿದನು.\n\nಪಾಂಡವರ ಕಡೆಯಿಂದ ಮೊತ್ತಮೊದಲಿಗೆ ಶ್ರೀಕೃಷ್ಣ ತನ್ನ ಶಂಖವನ್ನು ಮೊಳಗಿಸುತ್ತಾನೆ. ಶ್ರೀಕೃಷ್ಣನ ಶಂಖದ\nಹೆಸರು ಪಾಂಚಜನ್ಯ. ಈ 'ಪಾಂಚಜನ್ಯ' ಶಂಖದ ಹಿಂದೆ ಒಂದು ಕಥೆಯಿದೆ. ಶ್ರೀಕೃಷ್ಣ ತನ್ನ ವಿದ್ಯಾಭ್ಯಾಸವನ್ನು\nಮಾಡಿದ್ದು ಸಾಂದೀಪನಿ ಮುನಿಯ ಆಶ್ರಮದಲ್ಲಿ. ವಿದ್ಯಾಭ್ಯಾಸ ಮುಗಿಸಿ ಹಿಂತಿರುಗುವ ಸಮಯದಲ್ಲಿ ಶಿಷ್ಯರು\nಗುರುದಕ್ಷಿಣೆ ಕೊಡುವುದು ಸಾಮಾನ್ಯ. ಇಲ್ಲಿ ಕೃಷ್ಣ ತನ್ನ ಗುರುವಿಗೆ ಕೊಟ್ಟ ಗುರುದಕ್ಷಿಣೆ ಬಹಳ ವಿಶಿಷ್ಟವಾದುದು.\n'ಪಾಂಚಜನ' ಎನ್ನುವ ಅಸುರ ಸಾಂದೀಪನಿ ಮುನಿಯ ಪುತ್ರನನ್ನು ಕೊಂದಿದ್ದ. ತನ್ನ ವಿದ್ಯಾಭ್ಯಾಸ ಮುಗಿದು\nಹಿಂದಿರುಗುವ ಸಮಯದಲ್ಲಿ ಕೃಷ್ಣ ಗುರುದಂಪತಿಗಳಿಗೆ ಗುರುದಕ್ಷಿಣೆಯಾಗಿ ಅವರ ಪುತ್ರನನ್ನೇ ಮರಳಿಸಿದ. ಆ\nಪಾಂಚಜನ ಎನ್ನುವ ರಾಕ್ಷಸನಿದ್ದ ಶಂಖವೇ ಪಾಂಚಜನ್ಯ. ಪಾಂಚಜನ್ಯ-ಅಸುರ ಸಂಹಾರಕ ಹಾಗೂ\nಜ್ಞಾನಾನಂದದ ಸಂಕೇತ.\n\nಕೃಷ್ಣನ ಶಂಖನಾದದ ಬೆನ್ನಿಗೇ ಅರ್ಜುನ ತನ್ನ 'ದೇವದತ್ತ' ಎನ್ನುವ ಶಂಖವನ್ನೂದಿದ. ವಾನಪ್ರಸ್ಥ ಕಾಲದಲ್ಲಿ\nಅಸುರರ ವಿರುದ್ಧ ಹೊರಾಡಿದ್ದಕ್ಕಾಗಿ ಅರ್ಜುನನಿಗೆ ಇಂದ್ರ ದೇವಲೋಕದಲ್ಲಿ ವಿಶಿಷ್ಟವಾದ ಕಿರೀಟವನ್ನು ತೊಡಿಸಿ\nಈ ಶಂಖವನ್ನು ಉಡುಗೊರೆಯಾಗಿ ಕೊಟ್ಟಿದ್ದ. ಈ ಶಂಖವೂ ಕೂಡಾ ದುಷ್ಟನಿಗ್ರಹದ ಸಂಕೇತ.\n\nಅರ್ಜುನನ ಶಂಖನಾದದ ನಂತರ ವೃಕೋದರನಾದ ಭೀಮನು ಪೌಂಡ್ರ ಎನ್ನುವ ಮಹಾಶಂಖವನ್ನು ಊದಿದನು.\nಇಲ್ಲಿ ಭೀಮನನ್ನು ವೃಕೋದರ ಎಂದು ಸಂಬೋಧಿಸಿದ್ದಾರೆ. ವೃಕೋದರ ಎಂದರೆ ಇಡೀ ವಿಶ್ವವನ್ನು ಸುಡಬಲ್ಲ\nಅಗ್ನಿಯನ್ನು ಉದರದಲ್ಲಿ ಧರಿಸಿದವನು ಎಂದರ್ಥ. ಭೀಮ ಎಂತಹ ಪರಾಕ್ರಮಶಾಲಿ ಎನ್ನುವುದನ್ನು ಇಲ್ಲಿ ಈ\nರೀತಿ ವ್ಯಕ್ತಪಡಿಸಿದ್ದಾರೆ.\n\nಈ ಶ್ಲೋಕದಲ್ಲಿ ಶ್ರೀಕೃಷ್ಣನನ್ನು ಹೃಷೀಕೇಶ ಎಂದು ಸಂಬೋಧಿಸಿದ್ದಾರೆ. ಹೃಷೀಕೇಶ ಎಂದರೆ ಹೃಷೀಕಗಳಿಗೆ\nಈಶ. ಇಲ್ಲಿ. ಹೃಷೀಕ ಎಂದರೆ ಇಂದ್ರಿಯಗಳು. ಆತ ಇಂದ್ರಿಯಗಳ ಸ್ವಾಮಿ. ನಮಗೆ ಪ್ರತಿಯೊಂದು\nಇಂದ್ರಿಯಗಳನ್ನು ದಯಪಾಲಿಸಿ , ಅದರಲ್ಲಿ ನಿಂತು ನೆಡೆಸುವವನು ಹೃಷೀಕಗಳ ಈಶನಾದ ಹೃಷೀಕೇಶ. ಕೇಶ\nಅನ್ನುವ ಶಬ್ದಕ್ಕೆ ಸೂರ್ಯಕಿರಣ ಎನ್ನುವ ಅರ್ಥವಿದೆ. ಸೂರ್ಯನ ಕಿರಣದಲ್ಲಿ ಏಳು ಬಣ್ಣವಿದೆ. ಈ ಏಳು ವರ್ಣದಲ್ಲಿ\nತುಂಬಿ ಬದುಕಿಗೆ ಹರ್ಷವನ್ನು ಕೊಡತಕ್ಕಂತಹ ಭಗವಂತ ಹೃಷೀಕೇಶಃ",
  "1.16": "ಅನಂತವಿಜಯಮ್‌ ರಾಜಾ ಕುಂತೀಪುತ್ರಃ ಯುಧಿಷ್ಠಿರಃ |\nನಕುಲಃ ಸಹದೇವಃ ಚ ಸುಘೋಷ ಮಣಿಪುಷ್ಪಕೌ -- ಕುಂತೀಪುತ್ರನಾದ ರಾಜ ಯುಧಿಷ್ಠಿರ ಅನಂತವಿಜಯವನ್ನು,\nನಕುಲ ಸಹದೇವರು ಸುಘೋಷ ಮತ್ತು ಮಣಿಪುಷ್ಟವೆಂಬ ಶಂಖವನ್ನೂದಿದರು\n\nಭೀಮನ ನಂತರ ಕುಂತಿಯ ಹಿರಿಮಗ, ದೊರೆ ಯಧಿಷ್ಠಿರ- ಧರ್ಮ ಮತ್ತು ವಿಜಯದ ಸಂಕೇತವಾದ\n'ಅನಂತವಿಜಯ' ಎನ್ನುವ ಶಂಖವನ್ನು ಊದಿದನು. ನಕುಲ ಹಾಗೂ ಸಹದೇವರು ಸುಘೋಷ ಮತ್ತು\nಮಣಿಪುಷ್ಟವೆಂಬ ಶಂಖವನ್ನು ಕ್ರಮಬದ್ಧವಾಗಿ ಮೊಳಗಿಸಿದರು.\n\nಮಹಾಭಾರತದಲ್ಲಿ ಬೇರೆ ಯಾವ ರಾಜರ ಶಂಖದ ಹೆಸರಿನ ಬಗ್ಗೆ ಎಲ್ಲಿಯೂ ಉಲ್ಲೇಖವಿಲ್ಲ. ಪಾಂಡವರ ಐದು\nಶಂಖಗಳ ಹೆಸರನ್ನು ಭಗವದ್ಗೀತೆಯಲ್ಲಿ ಮಾತ್ರ ಕಾಣಬಹುದು. ಪ್ರಾಯಶಃ ಇದು ನಮಗೆ ನಿತ್ಯ\nಸ್ಮರಣೀಯವಾಗಿರಬೇಕು. ಎನ್ನುವ ಉದ್ದೇಶದಿಂದ ಗೀತೆಯಲ್ಲಿ ಈ ಐದು ಹೆಸರನ್ನು ವಿಶೇಷವಾಗಿ\nಉಲ್ಲೇಖಿಸಿರಬಹುದು.",
  "1.17": "ಕಾಶ್ಯಃ ಚ ಪರಮ ಇಷು ಆಸಃ ಶಿಖಂಡೀ ಚ ಮಹಾರಥಃ |\nಧೃಷ್ಟದ್ಯುಮ್ನಃ ವಿರಾಟಃ ಚ ಸಾತ್ಯಕಿಃ ಚ ಅಪರಾಜಿತಃ -- ಹಿರಿಯ ಬಿಲ್ದೋಜ ಕಾಶಿರಾಜ, ಹಿರಿಯ ತೇರಾಳು\n\nಶಿಖಂಡಿ ಸೇರಿದಂತೆ, ಧೃಷ್ಟದ್ಯುಮ್ನ ಮತ್ತು ವಿರಾಟ, ಸೋಲರಿಯದ ಸಾತ್ಯಕಿಯೊಂದಿಗೆ ಶಂಖನಾದ\nಮಾಡಿದರು.\n\nತದನಂತರ ಹಿರಿಯ ಬಿಲ್ಲೋಜ ಕಾಶಿರಾಜ, ಹಿರಿಯ ತೇರಾಳು ಶಿಖಂಡಿ, ಧೃಷ್ಟದ್ಯುಮ್ನ ಮತ್ತು ವಿರಾಟ,\nಸೋಲರಿಯದ ಸಾತ್ಯಕಿ, ಹೀಗೆ ಒಬ್ಬೊಬ್ಬರಾಗಿ ಶಂಖ ನಾದವನ್ನು ಮಾಡಿದರು.\n\nಇಲ್ಲಿ ಶಿಖಂಡಿಯನ್ನು ಮಹಾರಥ ಎಂದು ಸಂಬೋಧಿಸಿರುವುದನ್ನು ನಾವು ಗಮನಿಸಬೇಕು. ಬಹಳಷ್ಟು ಜನ\nಶಿಖಂಡಿ ಎಂದರೆ ನಪುಂಸಕ ಎಂದು ತಿಳಿದಿರುತ್ತಾರೆ. ಆದರೆ ಶಿಖಂಡಿ ಎಂದರೆ ನಪುಂಸಕ ಅಲ್ಲ. ಶಿಖಂಡಿ ಎಂದರೆ\nಮೂಲಭೂತವಾಗಿ ಶಿಖಂಡ(ಶಿಖ-ಅಂಡ )ಉಳ್ಳವನು. ಇಲ್ಲಿ ಶಿಖ ಎಂದರೆ ತಲೆಗೂದಲು. ತಲೆ ಕೂದಲನ್ನು\nಚೆನ್ನಾಗಿ ಬಾಚಿ ಹಿಂದೆ ಮೊಟ್ಟೆಯಂತೆ ಕಟ್ಟುವವರು ಶಿಖಂಡಿಗಳು. ಮಹಾಭಾರತದ ಈ ಶಿಖಂಡಿ ಹುಟ್ಟಿದಾಗ\nಹೆಣ್ಣಾಗಿದ್ದು , ಆ ಬಳಿಕ ಗಂಡಾದ ಮಹಾರಥ. ಈತ 'ಸ್ತ್ರೀಪೂರ್ವವಾದ್ದರಿಂದ' ಭೀಷ್ಮಾಚಾರ್ಯರು ಆತನ ವಿರುದ್ಧ\nಬಾಣ ಪ್ರಯೋಗ ಮಾಡಿರಲಿಲ್ಲ.",
  "1.18": "ದ್ರುಪದಃ ದ್ರೌಪದೇಯಾಃ ಚ ಸರ್ವಶಃ ಪೃಥಿವೀಪತೇ |\nಸೌಭದ್ರಃ ಚ ಮಹಾಬಾಹುಃ ಶಂಖಾನ್‌ ದಧ್ಮುಃ ಪೃಥಕ್‌ ಪೃಥಕ್‌ -- ಓ ನೆಲದೊಡೆಯನೇ; ದ್ರುಪದ, ದ್ರೌಪದಿಯ\nಮಕ್ಕಳು ಸೇರಿದಂತೆ, ತುಂಬುತೋಳಿನ ಮಹಾಪರಾಕ್ರಮಿ ಅಭಿಮನ್ಯು. ಹೀಗೆ ಎಲ್ಲರೂ, ಒಬ್ಬೊಬ್ಬರಾಗಿ ಶಂಖವನ್ನೂದಿದರು.\n\nಇಲ್ಲಿ ಸೂಕ್ಷ್ಮವಾಗಿ ನೋಡಿದಾಗ ಪಾಂಡವರ ಕಡೆ ಇದ್ದ ಶಿಸ್ತು(Discipline) ಎದ್ದು ಕಾಣುತ್ತದೆ. ಕೌರವರ\nಪಾಳಯದಿಂದ ಗದ್ದಲರೂಪದ ಶಂಖ ನಗಾರಿಗಳ ಸದ್ದಿಗೆ ಉತ್ತರವಾಗಿ ಪಾಂಡವರು ಶಿಸ್ತುಬದ್ಧವಾಗಿ,\nಕ್ರಮಬದ್ಧವಾಗಿ ಶಂಖನಾದ ಮಾಡುತ್ತಾರೆ. ಮನಃಶಾಸ್ತ್ರೀಯವಾಗಿ ನೋಡಿದಾಗ, ಶಿಸ್ತುಬದ್ಧವಾದ ಚಿಕ್ಕ ಸೇನೆ\nಅಶಿಸ್ತಿನಿಂದ ಕೂಡಿದ ಬಹುದೊಡ್ಡ ಸೇನೆಯ ಎದೆಯನ್ನು ಹೇಗೆ ನಡುಗಿಸಬಲ್ಲದು ಎನ್ನುವುದನ್ನು ಇಲ್ಲಿ ನಾವು\nಕಂಡುಕೊಳ್ಳಬಹುದು. ಭಗವಂತನಿಗೆ ಸರ್ವಸಮರ್ಪಣೆ ಭಾವದಲ್ಲಿ, ಯಾವುದೇ ಅಹಂಕಾರವಿಲ್ಲದೆ, ಭಗವಂತನ\nಸಾರಥ್ಯದಲ್ಲಿ, ಧರ್ಮಯದ್ಧಕ್ಕೆ ಸಿದ್ಧವಾದ ಪಾಂಡವ ಸೇನೆ-ಮಾನಸಿಕವಾಗಿ ಸಂಪೂರ್ಣ ಸಿದ್ಧವಾಗಿತ್ತು.\nಅಹಂಕಾರದ ಅಮಲಿನಲ್ಲಿ, ಅಧಿಕಾರದ ಆಸೆಯಿಂದ, ಮಾನಸಿಕ ಸ್ಥಿಮಿತ ಕಳೆದುಕೊಂಡು, ಭಗವಂತನ ವಿರುದ್ಧ\nನಿಂತ ದುರ್ಯೋಧನನ ಮುಂದಾಳತ್ವದಲ್ಲಿನ ಕೌರವಸೇನೆ- ಈಗಾಗಲೇ ಆತ್ಮವಿಶ್ವಾಸವನ್ನು ಕಳೆದುಕೊಂಡಿತ್ತು.\nಇಲ್ಲಿ ಕಾಣುವ ಇನ್ನೊಂದು ವಿಶೇಷತೆ ಎಂದರೆ- ಪಾಂಡವರ ಕಡೆಯಿಂದ ಕ್ರಮಬದ್ಧವಾಗಿ ಹದಿನೆಂಟು ಮಂದಿ\nಶಂಖನಾದ ಮಾಡಿದ್ದಾರೆ. ಸಂಖ್ಯಾಶಾಸ್ತ್ರವನ್ನು ನೋಡಿದಾಗ, ಅಕ್ಷರಾಂಕದ ಪದ್ಧತಿಯಲ್ಲಿ ಹದಿನೆಂಟು ಎಂದರೆ\n\nಜಯ. ಜ-ಯ. ಅಕ್ಷರಾಂಕದಲ್ಲಿ ಮೊದಲನೆಯದು ಏಕ ಸ್ಥಾನ, ಎರಡನೇಯದು ದಶಕ ಸ್ಥಾನ. ಆದ್ದರಿಂದ ಜ-ಯ ಎಂದರೆ ಎಂಬತ್ತೊಂದು ಅಲ್ಲ- ಹದಿನೆಂಟು. ಜಯದ ಸಂಕೇತವಾದ 'ಹದಿನೆಂಟು ಶಂಖನಾದ' ಪಾಂಡವರ\nಪಾಳಯದಲ್ಲಿ ಮೊಳಗಿತು ಎನ್ನುವಲ್ಲಿಗೆ ಭಗವದ್ಗೀತೆಯ ಹದಿನೆಂಟನೇ ಶ್ಲೋಕ ಮುಗಿಯಿತು!",
  "1.19": "ಸ ಘೋಷಃ ಧಾರ್ತರಾಷ್ಟ್ರಾ ಣಾಮ್‌ ಹೃದಯಾನಿ ವ್ಯದಾರಯತ್‌ |\nನಭಃ ಚ ಪೃಥಿವೀಮ್‌ ಚ ಏವ ತುಮುಲಃ ವ್ಯನುನಾದಯನ್‌ -- ಆ ಸದ್ದು ನೆಲ-ಮುಗಿಲು ತಬ್ಬಿ, ಪಡಿನುಡಿದು\nಅಬ್ಬರಿಸಿ, ಧಾರ್ತರಾಷ್ಟ್ರನೆಂದು ಹೆಸರಾದ ನಿನ್ನ ಮಕ್ಕಳ ಎದೆಗಳಿಗಬ್ಬರಿಸಿತು.\n\nಇಲ್ಲಿ ಸಂಜಯನು ಧೃತರಾಷ್ಟ್ರನ ಮಕ್ಕಳನ್ನು 'ಧಾರ್ತರಾಷ್ಟ್ರಾಣಾಂ' ಎಂದು ಸಂಬೋಧಿಸುತ್ತಾನೆ. ಏಕೆಂದರೆ\nಇದು ಅವರ ಉಪನಾಮ(Surname). ಈ ಹಿಂದೆ \"ನನ್ನ ಮಕ್ಕಳು ಮತ್ತು ಪಾಂಡವರು\" ಎಂದು ಸಂಬೋಧಿಸಿದ್ದ\nಧೃತರಾಷ್ಟ್ರನಿಗೆ ಸಂಜಯನ ಕುಹಕದ ಉತ್ತರವಿದು.\n\nಸಂಜಯ ಹೇಳುತ್ತಾನೆ: “ಪಾಂಡವರ ಕಡೆಯಿಂದ ಕ್ರಮಬದ್ಧವಾಗಿ ಮೊಳಗಿದ ಶಂಖನಾದ, ನೆಲಮುಗಿಲನ್ನು\nತುಂಬಿ, ಪಡಿನುಡಿದು ಅಬ್ಬರಿಸಿ, ಧಾರ್ತರಾಷ್ಟ್ರನೆಂದು ಹೆಸರಾದ ನಿನ್ನ ಮಕ್ಕಳ ಎದೆಯನ್ನು ಸೀಳಿತು” ಎಂದು. ಈ\nಹಿಂದೆ ಹೇಳಿದಂತೆ ಪಾಂಡವರ ಶಿಸ್ತುಬದ್ಧ ನಡೆ ಈಗಾಗಲೇ ಕೌರವರ ಎದೆಯನ್ನು ಭೇದಿಸಿತ್ತು. ಯುದ್ಧ\nಪ್ರಾರಂಭವಾಗುವ ಮೊದಲೇ ಪಾಂಡವರು ಕೌರವರನ್ನು ಮಾನಸಿಕವಾಗಿ ಸೋಲಿಸಿದ್ದರು.",
  "1.20": "ಅಥ ವ್ಯವಸ್ಥಿತಾನ್‌ ದೃಷ್ಟ್ವಾ ಧಾರ್ತರಾಷ್ಟ್ರಾನ್‌ ಕಪಿದ್ವಜಃ |\n\nಪ್ರವೃತ್ತೇ ಶಸ್ತ್ರಸಂಪಾತೇ ಧನುಃ ಉದ್ಯಮ್ಯ ಪಾಂಡವಃ ॥\n\nಹೃಷೀಕೇಶಮ್‌ ತದಾ ವಾಕ್ಯಮ್‌ ಇದಮ್‌ ಆಹ ಮಹೀಪತೇ -- ಓ ದೊರೆಯೇ, ಹನುಮನ ದ್ವಜದ ಅರ್ಜುನ\nಧಾರ್ತರಾಷ್ಟ್ರರು ಸಜ್ಜಾದದ್ದನ್ನು ಕಂಡು, ಹೋರಾಟಕ್ಕೆ ತೊಡಗಲು ತನ್ನ ಬಿಲ್ಲನ್ನು ಅಣಿಗೊಳಿಸಿ, ಕೃಷ್ಣನನ್ನು\nಕುರಿತು ಈ ಮಾತನ್ನು ಹೇಳಿದನು.\n\nಎರಡೂ ಕಡೆ ಶಂಖನಾದವಾದಾಗ ಯುದ್ಧ ಪ್ರಾರಂಭವಾಗುತ್ತದೆ. ಈ ಸಂದರ್ಭದಲ್ಲಿ, ತನ್ನ ರಥದಲ್ಲಿ\nಆಂಜನೇಯನ ವಿಶೇಷ ಸನ್ನಿಧಾನವುಳ್ಳ ಅರ್ಜುನನು, ಇಂದ್ರಿಯಗಳ ಒಡೆಯನಾದ ಶ್ರೀಕೃಷ್ಣ(ಹೃಷೀಕೇಶ)ನನ್ನು\nಕುರಿತು ಮಾತನ್ನಾಡುತ್ತಾನೆ.\n\nಇಲ್ಲಿ ಅರ್ಜುನನ ರಥದಲ್ಲಿ ಪ್ರಾಣದೇವರ ವಿಶೇಷ ಸನ್ನಿಧಾನವಿತ್ತು. ನಮ್ಮ ದೇಹವೆಂಬ ರಥದಲ್ಲಿ ಕೂಡಾ\nಜೀವನನ್ನು ಸದಾ ಪ್ರಾಣ 'ಭಗವಂತನ ಸನ್ನಿಧಾನದಲ್ಲಿ' ರಕ್ಷಿಸುತ್ತಿರುತ್ತಾನೆ. ಎಲ್ಲಿ ಪ್ರಾಣನೋ ಅಲ್ಲಿ ಭಗವಂತನ\n\nಸನ್ನಿಧಾನ. ಪೌರಾಣಿಕವಾಗಿ ಅರ್ಜುನನ ರಥದಲ್ಲಿ ಆಂಜನೇಯನ ಸನ್ನಿ ಧಾನವಿರಲು ಕಾರಣ ವಾಯುದೇವರ\nಇನ್ನೊಂದು ರೂಪವಾದ ಭೀಮಸೇನ. ಸೌಗಂಧಿಕಾ ಪುಷ್ಪ ತರಲು ಹೊರಟ ಭೀಮಸೇನನನ್ನು ಹನುಮಂತ\nಬಾಲದಿಂದ ತಡೆದ. ಈ ಸಂದರ್ಭದಲ್ಲಿ ನಡೆದ ಘಟನೆಯಲ್ಲಿ ಆಂಜನೇಯ ತಾನು ವಿಶೇಷವಾಗಿ ಅರ್ಜುನನ\nರಥದಲ್ಲಿ ಸನ್ನಿಹಿತನಾಗಿರುತ್ತೇನೆ ಎಂದು ಭೀಮಸೇನನಿಗೆ ಮಾತು ಕೊಡುತ್ತಾನೆ. ಇಲ್ಲಿ ಭೀಮಸೇನ ಹಾಗೂ\nಆಂಜನೇಯ ಎನ್ನುವುದು ಪ್ರಾಣದೇವರ ಎರಡು ರೂಪ (ರಾಮ ಮತ್ತು ಪರಶುರಾಮ ಇದ್ದಂತೆ).\n\nತನ್ನ ಧ್ವಜದಲ್ಲಿ ಆಂಜನೇಯನ ಸನ್ನಿಧಾನ, ಕೈಯಲ್ಲಿ ಗಾಂಡೀವ, ರಥದ ಸಾರಥಿ ಕೃಷ್ಣ, ಜೊತೆಯಲ್ಲಿ ಮಹಾ\nಪರಾಕ್ರಮಿ ಭೀಮಸೇನ. ಈ ರೀತಿ ಯುದ್ಧಕ್ಕೆ ಸಜ್ಜಾದ ಅರ್ಜುನನನ್ನು ಅಹಂಕಾರ(Ego) ಕಾಡುತ್ತದೆ. ಈ\nಅಹಂಕಾರದಿಂದ ಆತ ಕೃಷ್ಣನನ್ನು ಕುರಿತು ಹೀಗೆ ಹೇಳುತ್ತಾನೆ:",
  "1.21": "ಅರ್ಜುನಃ ಉವಾಚ- ಅರ್ಜುನನು ನುಡಿದನು\nಸೇನಯೋಃ ಉಭಯೋಃ ಮಧ್ಯೇ ರಥಮ್‌ ಸ್ಥಾಪಯ ಮೇ ಅಚ್ಯುತ - 'ಅಳಿವಿರದ ಕೃಷ್ಣನೇ' ಎರಡು ಪಡೆಗಳ\nನಡುವೆ ನನ್ನ ರಥವನ್ನು ನಿಲ್ಲಿಸು.\n\nಈ ಶ್ಲೋಕದಲ್ಲಿ ನಾವು ಸೂಕ್ಷ್ಮವಾಗಿ ಅರ್ಜುನನ ಅಹಂಕಾರದ ಧ್ವನಿಯನ್ನು ಗಮನಿಸಬೇಕು. 'ಮೇ' ಅಂದರೆ\n\"ನನ್ನ'. ಅರ್ಜುನನ ರಥದ ಸಾರಥ್ಯವನ್ನು ಸ್ವಯಂ ಶ್ರೀಕೃಷ್ಣ ವಹಿಸಿದ್ದರೂ ಕೂಡಾ, ಇಲ್ಲಿ ಅಹಂಕಾರದಲ್ಲಿ ಆತ\nಕೃಷ್ಣನನ್ನು ಸಾಮಾನ್ಯ ಸಾರಥಿಯಂತೆ ಮಾತನಾಡಿಸಿ, ''ನನ್ನ ರಥವನ್ನು ಎರಡೂ ಸೈನ್ಯಗಳ ಮಧ್ಯದಲ್ಲಿ ನಿಲ್ಲಿಸು\nಎಂದು ಆಜ್ಞೆ ಮಾಡುವ ಧ್ವನಿಯಲ್ಲಿ ಹೇಳುತ್ತಾನೆ.\n\nಇಲ್ಲಿ ಅರ್ಜುನ ಶ್ರೀಕೃಷ್ಣನನ್ನು ಅಚ್ಯುತ ಎಂದು ಸಂಬೋಧಿಸಿದ್ದಾನೆ. ಅಚ್ಯುತ ಎಂದರೆ ಸ್ವಯಂ ಚ್ಯುತಿ ಇಲ್ಲದ,\nಭಕ್ತರ ಚ್ಯುತಿಯನ್ನು ಹರಣ ಮಾಡುವ ಭಗವಂತ. ಬಾಹ್ಯವಾಗಿ ಅಹಂಕಾರ ತೋರಿದರೂ ಕೂಡಾ, ಅರ್ಜುನನ\nಅಂತರಾತ್ಮ ಮಾತ್ರ ಎಚ್ಚರದಿಂದಿತ್ತು, ಆ ಅಂತರಾತ್ಮ ಆತನ ಬಾಯಲ್ಲಿ ಈ ನಾಮವನ್ನು ನುಡಿಸಿದೆ. ಅಹಂಕಾರ\nಎಂತಹ ಮಹಾತ್ಮರನ್ನೂ ಬಿಟ್ಟಿಲ್ಲ. ಒಮ್ಮೆ ನಮ್ಮ ಕೈಯಲ್ಲಿ ಬಲವಿದೆ ಎಂದು ತಿಳಿದಾಗ ನಾವು ಎಲ್ಲವನ್ನೂ\nಮರೆತು ಅಹಂಕಾರದ ದಾಸರಾಗುತ್ತೇವೆ. ಈ ಅಹಂಕಾರ ನಮ್ಮನ್ನು ಅಧೋಗತಿಗೆ ತಳ್ಳುತ್ತದೆ. ಅರ್ಜುನ\nಮಹಾಜ್ಞಾನಿ ಮತ್ತು ಶ್ರೀಕೃಷ್ಣನ ಭಕ್ತ. ತನ್ನ ಭಕ್ತ ಅಹಂಕಾರಕ್ಕೊಳಪಟ್ಟಾಗ, ಶ್ರೀಕೃಷ್ಣ ಯಾವ ರೀತಿ ಪ್ರತಿಕ್ರಿಯೆ\nತೋರುತ್ತಾನೆ ಎನ್ನುವುದನ್ನು ಮುಂದಿನ ಶ್ಲೋಕಗಳಲ್ಲಿ ನೋಡೋಣ.\n\nಯಾವದೇತಾನ್‌ ನಿರೀಕ್ಷೇಽಹಂ ಯೋದ್ಧುಕಾಮಾನವಸ್ಥಿತಾನ್‌ |\nಕೈರ್ಮಯಾ ಸಹ ಯೋದ್ಧವ್ಯಮಸ್ಮಿನ್‌ ರಣಸಮುದ್ಯಮೇ",
  "1.22": "ಯಾವತ್‌ ಏತಾನ್‌ ನಿರೀಕ್ಷೇ ಅಹಮ್‌ ಯೋದ್ಧುಕಾಮಾನ್‌ ಅವಸ್ಥಿತಾನ್‌ |\nಕೈ: ಮಯಾ ಸಹ ಯೋದ್ಧವ್ಯಮ್‌ ಅಸ್ಮಿನ್‌ ರಣ ಸಮುದ್ಯಮೇ -- ಕಾದಾಡಲು ಬಯಸಿ ನೆರೆದ ಇವರತ್ತ ನಾನೊಮ್ಮೆ\n\nಕಣ್ಣು ಹಾಯಿಸುತ್ತೇನೆ. ಈ ಕದನದ ಕಾಯಕದಲ್ಲಿ ಯಾರು ನನ್ನ ಜೊತೆ ಹಾಗೂ ಯಾರ ಜೊತೆ ನಾನು\nಕಾದಬೇಕು ಎಂದು?\n\nಮಹಾಭಾರತ ಯುದ್ಧ ಇತಿಹಾಸದಲ್ಲಿ ದಾಖಲೆಯಾದ ಮೊದಲ ಜಾಗತಿಕ ಯುದ್ಧ. ಇಂತಹ ಯುದ್ಧದ\nಮಂಚೂಣಿಯಲ್ಲಿ ನಿಂತ ಅರ್ಜುನ ಅಹಂಕಾರದಿಂದ ಮಾತನಾಡುತ್ತಿದ್ದಾನೆ. ಆತ ಶ್ರೀಕೃಷ್ಣನಲ್ಲಿ \"ಇಲ್ಲಿ ನೆರೆದ\nಇವರತ್ತ ನಾನೊಮ್ಮೆ ಕಣ್ಣು ಹಾಯಿಸಬೇಕು. ನನ್ನ ವಿರುದ್ಧ ಯುದ್ಧ ಮಾಡಲು ಬಂದವರು ಯಾರು, ಹಾಗೂ ನನ್ನ\nಕಡೆಯಿಂದ ನನ್ನ ಸಹ ಯುದ್ಧ ಮಾಡಲು ಬಂದವರು ಯಾರು ಎಂದು ನಾನೊಮ್ಮೆ ನೋಡಬೇಕು” ಎನ್ನುತ್ತಾನೆ.\nಇಲ್ಲಿ \"ನನ್ನೊಂದಿಗೆ ಯುದ್ಧ ಮಾಡಲು ಬಂದವರನ್ನೊಮ್ಮೆ ನೋಡಬೇಕು\" ಎನ್ನುವಲ್ಲಿ ಅಹಂಕಾರಭರಿತ\nವ್ಯಂಗ್ಯವಿದೆ. ತಾನು ಮಹಾವೀರ, ತನ್ನೆದುರು ನೆರೆದ ಈ ಸೇನೆ ನನಗೆ ಏನೂ ಅಲ್ಲ ಎನ್ನುವ ಸೊಕ್ಕಿನ ಮಾತಿದು.",
  "1.23": "ಯೋತ್ಸ್ಯಮಾನಾನ್‌ ಅವೇಕ್ಷೇ ಅಹಮ್‌ ಯೇ ಏತೇ ಅತ್ರ ಸಮಾಗತಾಃ |\n\nಧಾರ್ತರಾಷ್ಟ್ರಸ್ಯ ದುರ್ಬುದ್ಧೇ ಯುದ್ಧೇ ಪ್ರಿಯ ಚಿಕೀರ್ಷವಃ -- ಇಲ್ಲಿ ನೆರೆದ: ಈ ಕಾದ ಹೊರಟವರನ್ನು,\nಬುದ್ಧಿಗೇಡಿಯಾದ ದುರ್ಯೋಧನನ ಹಿತವನ್ನು ಬಯಸಿ ಯುದ್ಧದಲ್ಲಿ ಆತನಿಗೆ ಹೆಗಲು ಕೊಡ ಬಯಸಿದವರನ್ನು,\nನಾನೊಮ್ಮೆ ನೋಡುತ್ತೇನೆ ಎನ್ನುತ್ತಾನೆ ಅರ್ಜುನ.\n\n\"ಬುದ್ಧಿಗೇಡಿ ದುರ್ಯೋಧನನಿಗೆ ಜಯವಾಗಬೇಕು ಎಂದು ಬಯಸಿ, ನಮಗೆ ತೊಂದರೆ ಕೊಡಲು ನನ್ನ ವಿರುದ್ಧ\nನಿಂತವರನ್ನೊಮ್ಮೆ ನಾನು ನೋಡಬೇಕು” ಎಂದು ಅರ್ಜುನ ಶ್ರೀಕೃಷ್ಣನಲ್ಲಿ ಆಜ್ಞಾರೂಪಿ ಸ್ವರದಲ್ಲಿ ಹೇಳುತ್ತಾನೆ.\nಇಲ್ಲಿ “ನನ್ನ ವಿರುದ್ಧ ನಿಂತವರನ್ನು ನಾನೊಮ್ಮೆ ನೋಡಬೇಕು” ಎಂದು ಶ್ರೀಕೃಷ್ಣನಲ್ಲಿ ಹೇಳುತ್ತಿರುವ ಅರ್ಜುನ\nಅಹಂಕಾರದ ದಾಸನಾಗಿರುವುದು ಸ್ಪಷ್ಟವಾಗಿ ನಮಗೆ ಕಾಣುತ್ತದೆ. ಈ ಅಹಂಕಾರದಲ್ಲಿ ಅರ್ಜುನ ಭಗವಂತನನ್ನೇ\nಮರೆತು ಮಾತನಾಡುತ್ತಿದ್ದಾನೆ.",
  "1.24": "ಸಂಜಯ ಉವಾಚ- ಸಂಜಯನು ಹೇಳಿದನು:\n\nಏವಮ್‌ ಉಕ್ತಃ ಹೃಷೀಕೇಶಃ ಗುಡಾಕೇಶೇನ ಭಾರತ |\n\nಸೇನಯೋಃ ಉಭಯೋಃ ಮಧ್ಯೇ ಸ್ಥಾಪಯಿತ್ವಾ ರಥ ಉತ್ತಮಮ್‌. ಓ ಭರತವಂಶದ ದೊರೆಯೇ,\nಗುಡಾಕೇಶನ ಮಾತನ್ನು ಆಲಿಸಿದ ಹೃಷೀಕೇಶ, ಎರಡು ಸೈನ್ಯದ ಮಧ್ಯೆ ಹಿರಿಯ ತೇರನ್ನು ನಿಲ್ಲಿಸಿದ.\n\nಇಂದ್ರಿಯದ ದೊರೆಯಾದ ಶ್ರೀಕೃಷ್ಣನು ಏನೂ ಮಾತನಾಡದೇ, ರಥವನ್ನು ಎರಡು ಸೈನ್ಯದ ಮಧ್ಯೆ ನಿಲ್ಲಿಸಿದ.\nಇಲ್ಲಿಂದ ಮುಂದೆ ನಾವು ಶ್ರೀಕೃಷ್ಣನ ಪ್ರತಿಯೊಂದು ನಡೆಯಲ್ಲಿ ಮನಃಶಾಸ್ತ್ರೀಯ ಚಿಕಿತ್ಸಾ\nಪದ್ಧತಿಯನ್ನು ಕಾಣಬಹುದು. ಅಹಂಕಾರವೆನ್ನುವುದು ಒಂದು ಮಾನಸಿಕ ಸ್ಥಿತಿ. ನಾವು\nಅಂತಹ ಸ್ಥಿತಿಯಿಂದ ಹೊರಬರಬೇಕಾದರೆ, ನಮಗೆ ಮಾನಸಿಕ ಚಿಕಿತ್ಸೆ ಬೇಕು. ಅದನ್ನೇ ಕೃಷ್ಣ ಇಲ್ಲಿ ಮಾಡಿ\nತೋರಿಸಿದ್ದಾನೆ. ಇಂತಹ ಶ್ರೀಕೃಷ್ಣನನ್ನು ನಾವು ಮನಃಶಾಸ್ತ್ರದ ಪಿತಾಮಹ(Father of Psychology) ಎಂದು\nಕರೆದರೆ ತಪ್ಪಾಗದು. ಮನಃಶಾಸ್ತ್ರದ ಅನೇಕ ವಿಷಯಗಳು ಗೀತೆಯ ಮೊದಲ ಅಧ್ಯಾಯದಲ್ಲೇ ಅಡಗಿದೆ.\n\nಈ ಶ್ಲೋಕದಲ್ಲಿ ಕೃಷ್ಣನನ್ನು ಹೃಷೀಕೇಶ ಎಂದೂ, ಹಾಗೂ ಅರ್ಜುನನನ್ನು ಗುಡಾಕೇಶನೆಂದೂ ಸಂಬೋಧಿಸಿದ್ದಾರೆ.\nಗುಡಾಕೇಶ ಎಂದರೆ ನಿದ್ದೆಯನ್ನು ಗೆದ್ದ ವೀರ ಎಂದರ್ಥ.",
  "1.25": "ಭೀಷ್ಮಃ ದ್ರೋಣ ಪ್ರಮುಖತಃ ಸರ್ವೇಷಾಮ್‌ ಚ ಮಹೀಕ್ಷೆತಾಮ್‌ |\n\nಉವಾಚ ಪಾರ್ಥ ಪಶ್ಯ ಏತಾನ್‌ ಸಮವೇತಾನ್‌ ಕುರೂನ್‌ ಇತಿ - ಭೀಷ್ಮ, ದ್ರೋಣರು, ಹಾಗೂ ಇತರ ಅರಸರು\nನೇರವಾಗಿ ಕಣ್ಣಿಗೆ ಬೀಳುವಂತೆ ರಥವನ್ನು ನಿಲ್ಲಿಸಿ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಹೇ ಪಾರ್ಥಾ, ನೋಡು ಈ ನೆರೆದ\nಕುರುಗಳನ್ನು” ಎಂದು.\n\nಶ್ರೀಕೃಷ್ಣನು. ಅರ್ಜುನನ ಅಣತಿಯಂತೆ ರಥವನ್ನು ಎರಡೂ ಸೈನ್ಯದ ಮಧ್ಯದಲ್ಲಿ ತಂದು, ಭೀಷ್ಮ-ದ್ರೋಣರು\nಮತ್ತು ಎಲ್ಲಾ ಅರಸರು ನೇರವಾಗಿ ಕಣ್ಣಿಗೆ ಕಾಣುವಂತೆ ನಿಲ್ಲಿಸಿ, ಭಾಂದವ್ಯವನ್ನು ಬಡಿದೇಳಿಸುವ ಧ್ವನಿಯಲ್ಲಿ\nಹೇಳುತ್ತಾನೆ: \"ಹೇ ಪಾರ್ಥಾ, ಇಲ್ಲಿ ಸೇರಿರುವ ನಿನ್ನ 'ಕುರುಗಳನ್ನು' ನೋಡು\" ಎಂದು.\n\nಇದು ಶ್ರೀಕೃಷ್ಣನ ಅದ್ಭುತ ಮಾನಸಿಕ ಚಿಕಿತ್ಸೆ (Psycho therapy). ಇಲ್ಲಿ ಅರ್ಜುನನ ಮನಃಸ್ಥಿತಿಯ ಪರೀಕ್ಷೆ\nನಡೆಯುತ್ತಿದೆ. ಅರ್ಜುನ ಒಬ್ಬ ರಾಜ. ಆತನ ಮೂಲ ಕರ್ತವ್ಯ ಧರ್ಮದ ಪರ ಹೋರಾಟ ಮಾಡುವುದು ಹಾಗೂ\nಪ್ರಜಾಪಾಲನೆ ಮಾಡುವುದು. ಹೀಗೆ ತನ್ನ ಕರ್ತವ್ಯಪಾಲನೆ ಮಾಡುತ್ತಿರುವಾಗ, ಧರ್ಮದ ವಿರುದ್ಧ ನಿಂತವರು\nಯಾರೇ ಆಗಿರಲಿ, ಅವರನ್ನು ಶಿಕ್ಷಿಸುವುದು ಆತನ ಕರ್ತವ್ಯ. ಆತನೊಬ್ಬ ನ್ಯಾಯಾಧೀಶನಿದ್ದಂತೆ. ಇಲ್ಲಿ ನನ್ನ\nಕುಟುಬದವರು, ನನ್ನ ಬಂಧುಗಳು, ನನ್ನ ಸ್ನೇಹಿತರು ಎನ್ನುವ ತಾರತಮ್ಯ ಸಲ್ಲದು. ಇಂತಹ ಜವಾಬ್ದಾರಿಯುತ\nಕಾರ್ಯದಲ್ಲಿ ತೊಡಗಿದ ಅರ್ಜುನ, ತನ್ನ ಸಮೀಪಬಂಧುಗಳನ್ನು, ಗುರುಗಳನ್ನು ಕಂಡಾಗ ಹೇಗೆ\nಪರಿತಪಿಸುತ್ತಾನೆ ಎನ್ನುವುದನ್ನು ಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ನೋಡೋಣ.",
  "1.26": "ಶ್ವಶುರಾನ್‌ ಸುಹೃದಶ್ಚೆವ ಸೇನಯೋರುಭಯೋರಪಿ ।\n\nತತ್ರ ಅಪಶ್ಯತ್‌ ಸ್ಥಿತಾನ್‌ ಪಾರ್ಥಃ ಪಿತೃನ್ ಅಥ ಪಿತಾಮಹಾನ್‌ |\n\nಆಚಾರ್ಯಾನ್‌ ಮಾತುಲಾನ್‌ ಭ್ರಾತೃನ್ ಪುತ್ರಾನ್‌ ಪೌತ್ರಾನ್‌ ಸಖೀನ್‌ ತಥಾ ॥\n\nಶ್ವಶುರಾನ್‌ ಸುಹೃದಃ ಚ ಏವ ಸೇನಯೋಃ ಉಭಯೋಃ ಅಪಿ - ಅಲ್ಲಿ ಎರಡೂ ಕಡೆಯ ಪಡೆಗಳಲ್ಲಿ\nನೆರೆದವರನ್ನು ಅರ್ಜುನನು ಕಂಡನು. ತಂದೆಯಂತಿರುವವರನ್ನು, ಅಜ್ಜಂದಿರನ್ನು, ಗುರುಗಳನ್ನು,\nಸೋದರಮಾವಂದಿರನ್ನು, ಅಣ್ಣ-ತಮ್ಮಂದಿರನ್ನು, ಮಕ್ಕಳನ್ನು, ಮೊಮ್ಮಕ್ಕಳನ್ನು, ಸಂಗಾತಿಗಳನ್ನು\nಮಾವಂದಿರನ್ನು ಮತ್ತು ಗೆಳೆಯರನ್ನು.\n\nಕೃಷ್ಣನು ರಥವನ್ನು ಅರ್ಜುನನ ಆತ್ಮೀಯ ಬಂಧುಗಳ ಎದುರು ನಿಲ್ಲಿಸಿದ್ದರಿಂದ, ಅಲ್ಲಿ ನೆರೆದ ಎಲ್ಲರನ್ನೂ ಅರ್ಜುನ\nನೋಡುತ್ತಾನೆ. ಇಷ್ಟು ಹೊತ್ತು ಜಂಭದ ಮಾತನಾಡಿದ ಆತನಿಗೆ ಈಗ ತನ್ನೆದುರಿಗೆ ನಿಂತ ತಂದೆ ಸಮಾನರು,\nಅಜ್ಜಂದಿರು, ವಿದ್ಯೆ ಕೊಟ್ಟ ಆಚಾರ್ಯರು, ಸೋದರಮಾವಂದಿರು, ಅಣ್ಣತಮ್ಮಂದಿರು, ಮಕ್ಕಳು, ಮೊಮ್ಮೊಕ್ಕಳು,\nಸ್ನೇಹ ಸಂಗಾತಿಗಳು, ಮಾವಂದಿರು, ಹಿತೈಷಿಗಳು, ಎಲ್ಲರೂ ಎರಡೂ ಕಡೆಗಳಲ್ಲಿ ಕಾಣಿಸುತ್ತಾರೆ.\n\nಎಚ್ಚರದಿಂದ ಈ ಶ್ಲೋಕವನ್ನು ಗಮನಿಸಿದರೆ, ಅರ್ಜುನನಿಗೆ ಯುದ್ಧರಂಗದಲ್ಲಿ ಅನೇಕ ಮಂದಿ ಪ್ರಮುಖರಿದ್ದರೂ\nಕೂಡಾ ಅಲ್ಲಿ ಕಾಣಿಸಿದ್ದು ಕೇವಲ ಗುರು ಹಿರಿಯರು, ಬಂಧುಗಳು ಮತ್ತು ಆತ್ಮೀಯರು. ಇಲ್ಲಿ ಆತನಿಗೆ ಬಂಧು\nಪ್ರೇಮ ಎಚ್ಚರ ಆಗಿರುವುದು ಸ್ಪಷ್ಟವಾಗಿ ಕಾಣುತ್ತದೆ. ಕರ್ತವ್ಯನಿರತ ಜನಪಾಲಕ ರಾಜನಿಗೆ ಬಂಧು ಪ್ರೇಮ\nತರವಲ್ಲ. ಪ್ರಜಾಪಾಲಕನಾದವನಿಗೆ ಪ್ರಜಾಪಾಲನೆ ಮೂಲಧರ್ಮ. ಅದನ್ನು ಆತ ಎಂದೂ ಚ್ಯುತಿ ಬರದಂತೆ\nನಿರ್ವಹಿಸಬೇಕು. ಈ ರೀತಿ ಕಾರ್ಯ ನಿರ್ವಹಿಸುತ್ತಿರುವಾಗ “ನನ್ನ ಬಂಧುಗಳು, ನನ್ನ ಪರಿವಾರ' ಎಂದು\nಯಾವುದೇ ತಾರತಮ್ಯ ಮಾಡುವಂತಿಲ್ಲ.",
  "1.27": "ತಾನ್‌ ಸಮೀಕ್ಷ್ಯ ಸಃ ಕೌಂತೇಯಃ ಸರ್ವಾನ್‌ ಬಂಧೂನ್‌ ಅವಸ್ಥಿತಾನ್‌ |\nಕೃಪಯಾ ಪರಯಾ ಆವಿಷ್ಟಃ ವಿಷೀದನ್‌ ಇದಮ್‌ ಅಬ್ರವೀತ್‌ -- ಆ ಎಲ್ಲಾ ಬಂಧುಗಳು ಒಂದೆಡೆ ಸೇರಿರುವುದನ್ನು\nಕಂಡ ಅರ್ಜುನ ಕಡು ಕರುಣೆಗೊಳಗಾಗಿ, ಭಾವಪರವಶನಾಗಿ-ಹೀಗೆ ಹೇಳಿದನು\n\nಆ ಎಲ್ಲಾ ಬಂಧುಗಳು ಒಂದುಗೂಡಿರುವುದನ್ನು ಕಂಡ ಅರ್ಜುನ, ಕರುಣೆಗೊಳಗಾಗಿ, ಕಾರುಣ್ಯದಿಂದ,\nದುಃಖದಿಂದ, ತನ್ನ ತುಮುಲವನ್ನು ಕೃಷ್ಣನಲ್ಲಿ ತೋಡಿಕೊಳ್ಳುತ್ತಾನೆ.\n\nಇಲ್ಲಿಂದ ಮುಂದೆ ಅರ್ಜುನ ಅನೇಕ ರೀತಿಯಲ್ಲಿ ತನ್ನ ಅಳಲನ್ನು ಶ್ರೀಕೃಷ್ಣನ ಮುಂದೆ ತೊಡಿಕೊಳ್ಳುವುದನ್ನು\nಕಾಣುತ್ತೇವೆ. ಮುಂದಿನ ಶ್ಲೋಕಗಳನ್ನು ನೋಡುವ ಮೊದಲು ಇಲ್ಲಿ ಒಂದು ಪುಟ್ಟ ವಿಶ್ಲೇಷಣೆ ಮಾಡೋಣ.\nಗೀತೆಯನ್ನು ಓದುವಾಗ ಕೆಲವರಿಗೆ ಶ್ರೀಕೃಷ್ಣನ ನಡೆ ಅರ್ಥವಾಗುವುದಿಲ್ಲ. \"ಅಯ್ಯೋ- ಹೇಗೆ ನನ್ನ ಬಂಧುಗಳ\nವಿರುದ್ಧ ಹೋರಾಡಲಿ” ಎಂದು ಅರ್ಜುನ ಕೇಳಿದರೆ, ಕೃಷ್ಣ \"ಯುದ್ಧ ಮಾಡು” ಎಂದು ಹೇಳುತ್ತಾನೆ. ಇದು\nನ್ಯಾಯವೇ ಎನ್ನುವ ಪ್ರಶ್ನೆ ಹೆಚ್ಚಿನವರನ್ನು ಕಾಡುತ್ತದೆ. ಇಲ್ಲಿ ನಾವು ಗಮನಿಸಬೇಕಾದ ವಿಷಯವೆಂದರೆ, ಅರ್ಜುನ\n\nಒಬ್ಬ ಸಾಮಾನ್ಯ ವ್ಯಕ್ತಿಯಾಗಿ ಈ ಮಾತನ್ನು ಹೇಳಿದ್ದರೆ ಖಂಡಿತವಾಗಿ ನಾವು ಒಪ್ಪಬೇಕಾದ ವಿಷಯವಿದು. ಆದರೆ\nಇಲ್ಲಿ ಆತ ಭರತಖಂಡದ ರಕ್ಷಕನಾಗಿ ಧರ್ಮದ ಪರ ಹೋರಾಟಮಾಡಲು ಧರ್ಮರಾಯನ ಪರ ನಿಂತ ಅರಸ.\nಆತ ಒಂದು ವೇಳೆ \"ನಮಗೋಸ್ಕರ ಭರತ ಖಂಡದ ಜನರು ಸಾಯುವುದು ಬೇಡ\" ಎಂದಿದ್ದರೆ ಒಪ್ಪಬಹುದಿತ್ತು.\nಆದರೆ ಆತ ಹಾಗೆ ಹೇಳಲಿಲ್ಲ. ಆತನಿಗೆ ಅಲ್ಲಿ ಕಾಣಿಸಿದ್ದು ಕೇವಲ ಬಂಧುಗಳು. ರಾಜನಾದವನಿಗೆ ಧರ್ಮದ ಕಡೆ\nನಿಂತವನು ಮಾತ್ರ ಬಂಧು. ಧರ್ಮದ ವಿರುದ್ಧ ಯಾರೇ ನಿಂತಿರಲೀ ಆತ ಕೇವಲ ಅಪರಾಧಿ. ಅವರನ್ನು\nಶಿಕ್ಷಿಸುವುದು ರಾಜನ ಪರಮ ಧರ್ಮ. ನ್ಯಾಯ ಸ್ಥಾನದಲ್ಲಿ ನಿಂತ ನ್ಯಾಯಾಧೀಶ, ಅನ್ಯಾಯ ಮಾಡಿ ಬಂದ ತನ್ನ\nಬಂಧುವನ್ನು 'ನನ್ನ ಕಡೆಯವನು' ಎಂದು ಹೇಗೆ ಕ್ಷಮಿಸುವಂತಿಲ್ಲವೋ, ಹಾಗೇ ರಾಜನಾದವನೂ ಕೂಡಾ ಇಲ್ಲಿ\nನೋಡಬೇಕಾದದ್ದು ಧರ್ಮವನ್ನು ಹೊರತು ಬಂಧುತ್ವವನ್ನಲ್ಲ.\n\nಮುಂದೆ. ಅರ್ಜುನ ಅನೇಕ ರೀತಿಯಲ್ಲಿ ತನ್ನ ವಿತಂಡವಾದದಿಂದ(Arguments) ಶ್ರೀಕೃಷ್ಣನನ್ನು\nಸಮಜಾಯಿಸಲು (Convince) ನೋಡುತ್ತಾನೆ. ಆದರೆ ಶ್ರೀಕೃಷ್ಣ ಎಲ್ಲೂ ಈ ವಿತಂಡವಾದಕ್ಕೆ ನೇರ ಉತ್ತರ\nಕೊಡುವುದಿಲ್ಲ. ಏಕೆಂದರೆ ಒಂದು. ವೇಳೆ ಹಾಗೆ ಮಾಡಿದ್ದರೆ ಆತ ಬೇಡವಾದ ವಾದಕ್ಕೆ ಮಣೆ\nಹಾಕಿದಂತಾಗುತ್ತಿತ್ತು. ಮಾನಸಿಕ ತುಮುಲದಲ್ಲಿರುವ ಅರ್ಜುನ ಆಡುವ ಪ್ರತಿಯೊಂದು ಮಾತನ್ನೂ ಒಬ್ಬ\nಉತ್ತಮ ಕೇಳುಗನಂತೆ ಕೇಳಿ, ಆನಂತರ ಒಬ್ಬ ಮಾನಸಿಕ ರೋಗಿಗೆ ಚಿಕಿತ್ಸೆ ಕೊಡುವ ರೀತಿಯಲ್ಲಿ ಕೃಷ್ಣ\nನಡೆದಿರುವುದನ್ನು ನಾವು ಕಾಣುತ್ತೇವೆ.\n\nಬನ್ನಿ ಈ ಅಂಶಗಳನ್ನು ಗಮನದಲ್ಲಿಟ್ಟುಕೊಂಡು ಮುಂದಿನ ಶ್ಲೋಕವನ್ನು ನೋಡೋಣ.",
  "1.28": "ಅರ್ಜುನ ಉವಾಚ ।\nದೃಷ್ಟ್ವೇಮಂ ಸ್ವಜನಂ ಕೃಷ್ಣ ಯುಯುತ್ಸುಂ ಸಮುಪಸ್ಥಿತಮ್ ।\nಸೀದಂತಿ ಮಮ ಗಾತ್ರಾಣಿ ಮುಖಂ ಚ ಪರಿಶುಷ್ಯತಿ ॥೨೮॥\n\nವೇಪಥುಶ್ಚ ಶರೀರೇ ಮೇ ರೋಮಹರ್ಷಶ್ಚ ಜಾಯತೇ —\n\nಅರ್ಜುನನು ಹೇಳಿದನು: ಕೃಷ್ಣಾ, ಯುದ್ಧಾಸಕ್ತರಾಗಿ ಬಂದು ನಿಂತಿರುವ ಈ ನಮ್ಮ ಸ್ವಜನರನ್ನು ನೋಡಿ ನನ್ನ ಅಂಗಗಳು ಕುಸಿಯುತ್ತಿವೆ, ಬಾಯಿ ಒಣಗುತ್ತಿದೆ, ಶರೀರದಲ್ಲಿ ನಡುಕ ಉಂಟಾಗುತ್ತಿದೆ ಮತ್ತು ರೋಮಾಂಚನವಾಗುತ್ತಿದೆ.\n\nಯುಯುತ್ಸುಗಳಾದ ಸ್ವಜನರನ್ನು ನೋಡಿ - ಅರ್ಜುನನ ಮನಃಸಂಕಟವು ಶರೀರದಲ್ಲಿ ಇಳಿಯುತ್ತದೆ - 'ಗಾತ್ರಗಳು ಸೋಲುತ್ತಿವೆ, ಬಾಯಿ ಒಣಗುತ್ತಿದೆ.' ಇದು ಗೀತೆಯ ಉಪಕ್ರಮದ ಹಿನ್ನೆಲೆ.",
  "1.29": "ಅರ್ಜುನಃ ಉವಾಚ -- ಅರ್ಜುನ ಹೇಳಿದನು:\n\nದೃಷ್ಟಾ ಇಮಮ್‌ ಸ್ವಜನಮ್‌ ಕೃಷ್ಣ ಯುಯುತ್ಸುಮ್‌ ಸಮುಪಸ್ಥಿತಮ್‌ ॥\n\nಸೀದಂತಿ ಮಮ ಗಾತ್ರಾಣಿ ಮುಖಮ್‌ ಚ ಪರಿಶುಷ್ಯತಿ |\n\nವೇಪಥುಃ ಚ ಶರೀರೇ ಮೇ ರೋಮ ಹರ್ಷಃ ಚ ಜಾಯತೇ -- ಕೃಷ್ಣಾ, ಯುದ್ಧೋತ್ಸಾಹದಿಂದ ಇಲ್ಲಿ ನೆರೆದ ನಮ್ಮ\nಮಂದಿಯನ್ನು ನೋಡಿದಾಗ ನನ್ನ ಅಂಗಾಂಗಗಳು ಕಂಗೆಡುತ್ತಿವೆ. ಬಾಯಿಯೂ ಬತ್ತುತ್ತಿದೆ. ನನ್ನ ಮೈಯೆಲ್ಲವೂ\nನವಿರೆದ್ದು ನಡುಗುತ್ತಿದೆ.\n\nಅರ್ಜುನ ಹೇಳುತ್ತಾನೆ: \"ಇಲ್ಲಿ ನೆರೆದ ನನ್ನ ಹಿರಿಯ ಬಂಧುಗಳನ್ನು ನೋಡಿದಾಗ ನನ್ನ ಅಂಗಾಂಗಗಳು\nಮುದುಡುತ್ತಿವೆ. ನಾವು ಪರಸ್ಪರ ಸ್ನೇಹಪೂರ್ವಕವಾಗಿ ಬದುಕಬೇಕಾದವರು ಇಂದು ಈ ರಣರಂಗದಲ್ಲಿ\nಎದುರುಬದುರಾಗಿ ಹೊಡೆದಾಡಿಕೊಳ್ಳಲು ನಿಂತಿರುವುದನ್ನು ಕಂಡು ನನ್ನ ಮುಖ ನಾಚಿಕೆಯಿಂದ ಬಾಡುತ್ತಿದೆ.\n\nತಿಳುವಳಿಕೆಯುಳ್ಳ ನಾವೇ ಇಂತಹ ಅಸಹ್ಯ ಕೆಲಸಕ್ಕೆ ಇಳಿದುಬಿಟ್ಟೆವಲ್ಲಾ. ಈ ತೀರ್ಮಾನವನ್ನು ನಾವೇ ಮಾಡಿ\nಅದಕ್ಕೆ ನಾವೇ ಬದ್ಧರಾಗಿ ರಣರಂಗದಲ್ಲಿ ನಿಂತಿದ್ದೇವಲ್ಲ. ನಮ್ಮವರನ್ನು ನೋಡಿ ಮೈ ಮುದುಡುತ್ತಿದೆ. ಮುಖ\nಒಣಗಿ ಮಾತನಾಡಲು ಆಗುತ್ತಿಲ್ಲ. ಎಷ್ಟು ಕೆಳಮಟ್ಟ ಕ್ಕಿಳಿದೆವು ನಾವು. ಇದನ್ನು ಯೋಚಿಸಿದರೆ ನಡುಕ ಬರುತ್ತದೆ”\nಎನ್ನುತ್ತಾನೆ. ಇಲ್ಲಿ ಅರ್ಜುನನ ಮಾತಿನಲ್ಲಿ ಮೊದಲು ಅನುಕಂಪ, ಅದರಿಂದ ಲಜ್ಜೆ, ಅದರಿಂದ ಭಯ, ಅದರಿಂದ\nವಿಸ್ಮಯ ವ್ಯಕ್ತವಾಗಿರುವುದನ್ನು ನಾವು ಕಾಣುತ್ತೇವೆ.",
  "1.30": "ಗಾಂಡೀವಮ್‌ ಸ್ರಂಸತೇ ಹಸ್ತಾತ್‌ ತ್ವಕ್‌ ಚ ಏವ ಪರಿದಹ್ಯತೇ |\nನಚ ಶಕ್ನೋಮಿ ಅವಸ್ಥಾತುಂ ಭ್ರಮತಿ ಇವ ಚ ಮೇ ಮನಃ -- ಗಾಂಡೀವ ಕೈಯಿಂದ ಜಾರುತ್ತಿದೆ, ತೊಗಲು\nಉರಿಯೆದ್ದಿದೆ. ನಿಂತಲ್ಲಿ ನಿಲ್ಲಲಾಗುತ್ತಿಲ್ಲ. ನನ್ನ ಮನಸ್ಸು ಗೊಂದಲಮಯವಾಗುತ್ತಿದೆ.\n\nಒಬ್ಬ ವ್ಯಕ್ತಿ ತನ್ನ ಆತ್ಮ ವಿಶ್ವಾಸವನ್ನು ಕಳೆದುಕೊಂಡಾಗ, ಆತನ ಅಂತರಂಗದ ಅನುಭವ ದೈಹಿಕವಾಗಿ ಹೇಗೆ\nಹೊರಹೊಮ್ಮುತ್ತದೆ ಎನ್ನುವುದನ್ನು ಇಲ್ಲಿ ಕಾಣಬಹುದು. ಆತ್ಮವಿಶ್ವಾಸವಿರದ ವ್ಯಕ್ತಿ ತನ್ನ ಮುಷ್ಠಿ ಬಿಗಿ\nಹಿಡಿಯಲಾರ. ಇಲ್ಲಿ ಅರ್ಜುನನ ಸ್ಥಿತಿ ಕೂಡಾ ಹಾಗೇ ಆಗಿದೆ. ಆತ ಹೇಳುತ್ತಾನೆ: \"ಗಾಂಡೀವ ನನ್ನ ಕೈಯಿಂದ\nಜಾರುತ್ತಿದೆ, ಇಡೀ ಮೈ ಉರಿ ಎದ್ದ ಹಾಗೆ ಸಂಕಟವಾಗುತ್ತಿದೆ\" ಎಂದು. ಇದು ಒಳಗಿನ ಭಾವದ, ತುಮುಲದ\nಅಭಿವ್ಯಕ್ತ. ಒಮ್ಮೆ ಮನಸ್ಸು ಸ್ಥಿರವಿಲ್ಲದಿದ್ದರೆ ದೇಹಕೂಡಾ ಸ್ಥಿರವಿರಲಾರದು. ಅದೇ ರೀತಿ ದೇಹ ಸ್ಥಿರವಿಲ್ಲದಿದ್ದರೆ\nಮನಸ್ಸನ್ನು ಸ್ಥಿರಗೊಳಿಸುವುದು ಸಾಧ್ಯವಿಲ್ಲ. \"ಈ ರಥದಲ್ಲಿ ಕುಳಿತುಕೊಳ್ಳಲು ಆಗುತ್ತಿಲ್ಲ. ಮನಸ್ಸು\nಗೊಂದಲಮಯವಾಗಿದೆ\" ಎಂದು ಕೃಷ್ಣನಲ್ಲಿ ಅರ್ಜುನ ಪರಿತಪಿಸುತ್ತಾನೆ.",
  "1.31": "ನಿಮಿತ್ತಾನಿ ಚ ಪಶ್ಯಾಮಿ ವಿಪರೀತಾನಿ ಕೇಶವ |\nನ ಚ ಶ್ರೇಯಃ ಅನುಪಶ್ಯಾಮಿ ಹತ್ವಾ ಸ್ವಜನಮ್‌ ಆಹವೇ -- ಕೇಶವಾ, ಕೆಟ್ಟ ಶಕುನಗಳನ್ನೇ ಕಾಣುತ್ತಿದ್ದೇನೆ.\nಕದನದಲ್ಲಿ ನಮ್ಮ ಮಂದಿಯನ್ನೇಕೊಂದು ಏನು ಒಳಿತೋ ತಿಳಿಯದು.\n\n'ನಿಮಿತ್ತಗಳು'. ಎಂದರೆ ಶಕುನಗಳು. ಇಲ್ಲಿ ಅರ್ಜುನ ಹಿಂದೆ ನಡೆದ ಕೆಲವು ಕೆಟ್ಟ ಶಕುನಗಳನ್ನು\nನೆನಪಿಸಿಕೊಳ್ಳುತ್ತಾನೆ. ಈ ಶಕುನಗಳನ್ನು ಆತ ಯುದ್ಧ ಭೂಮಿಗೆ ಬರುವ ಮೊದಲೇ ಗಮನಿಸಿದ್ದ. ಆದರೆ ಆತನಿಗೆ\nಅದು ಈಗ ನೆನಪಿಗೆ ಬರುತ್ತಿದೆ.\n\nಹಿಂದಿನವರು ಶಕುನಗಳಿಗೆ ಬಹಳ ಮಹತ್ವ ಕೊಡುತ್ತಿದ್ದರು. ಈ ಪ್ರಪಂಚದಲ್ಲಿ ಎಲ್ಲವೂ ಒಂದಕ್ಕೊಂದು\nಬೆಸೆದುಕೊಂಡಿದೆ. ಒಂದು ಪರಮಾಣುವಿನಿಂದ ಹಿಡಿದು ಬ್ರಹ್ಮಾಂಡದ ತನಕ ಒಂದಕ್ಕೊಂದು ಸುಸಂಬದ್ಧವಾಗಿ\n\nಎಲ್ಲವೂ ಗಣಿತಬದ್ಧ. ಈ ಕಾರಣದಿಂದ ಯಾವುದನ್ನು ಬೇಕಾದರೂ ಗಣಿತಬದ್ಧವಾಗಿ ಕಂಡುಕೊಳ್ಳಬಹುದು. ಇದೇ\nಜ್ಯೋತಿಷ್ಯ, ಶಕುನ, ಪಂಚಾಗ ಇತ್ಯಾದಿ. ಇಲ್ಲಿ ಯಾವುದೂ ಆಕಸ್ಮಿಕವಲ್ಲ. ನಮಗೆ ತಿಳಿಯದಿದ್ದಾಗ ಮಾತ್ರ ಅದು\nನಮಗೆ ಆಕಸ್ಮಿಕ.\n\nಮಹಾಭಾರತ ಕಾಲದಲ್ಲಿ ಕಂಡ ಕೆಲವು ಶಕುನಗಳನ್ನು ಇಲ್ಲಿ ನೋಡೋಣ: ಆನೆಗಳು, ಕುದುರೆಗಳು ಯುದ್ಧಕ್ಕೆ\nಮೊದಲು ಕಣ್ಣೀರು ಸುರಿಸುತ್ತಿದ್ದವು. ನರಿಗಳು ಸೇನಾಪಡೆಯ ಸುತ್ತ ಉಳಿಡುತ್ತಿದ್ದವು. ಪ್ರಾಣಿಗಳಿಗೆ ರಕ್ತಪಾತದ\nಹಾಗೂ ಸಾವಿನ ಮುನ್ಸೂಚನೆ ಇರುತ್ತದೆ. ಮುಂದೆ ನಡೆಯುವುದನ್ನು ಅವು ನಿಖರವಾಗಿ ಗ್ರಹಿಸಬಲ್ಲವು. ಇದು\nಮಹಾಭಾರತ ಯುದ್ಧಕ್ಕೆ ಮೊದಲು ಕಂಡ ಒಂದು ಶಕುನ. ಇನ್ನು ಬ್ರಹ್ಮಾಂಡದಲ್ಲಿ ಹದಿಮೂರು ದಿನಗಳ\nಅಂತರದಲ್ಲಿ ಎರಡು ಗ್ರಹಣ ಮಹಾಭಾರತ ಯುದ್ಧಕಾಲದಲ್ಲಿ ಘಟಿಸಿದೆ. ಯುದ್ಧ ಪ್ರಾರಂಭವಾಗಿ ಐದನೇ ದಿನಕ್ಕೆ\nಒಂದು ಗ್ರಹಣ, ಪುನಃ ಹದಿಮೂರು ದಿನಗಳ ಅಂತರದಲ್ಲಿ ಇನ್ನೊಂದು ಗ್ರಹಣ. ಇದು ಮೃತ್ಯು ಸೂಚಕ ಭೀಕರ\nಶಕುನ. ಇದನ್ನು ವ್ಯಾಸರು ಮೊದಲೇ ಧೃತರಾಷ್ಟ್ರನಿಗೆ ತಿಳಿಸಿದ್ದರು. 'ಲೋಕಕಂಟಕನಾದ ನಿನ್ನ ಮಗನಿಂದ-\nಲೋಕ ನಾಶವಾಗುತ್ತದೆ' ಎಂದು.\n\nಹೀಗೆ ಹಿಂದೆ ನಡೆದ ಶಕುನಗಳನ್ನು ನೆನಪಿಸಿದ ಅರ್ಜುನ, ಕೃಷ್ಣನನ್ನು 'ಕೇಶವ' ಎಂದು ಸಂಬೋಧಿಸುತ್ತಾನೆ.\nಪ್ರಾರಂಭದಲ್ಲಿ 'ಕೃಷ್ಣ' ಎಂದು ಆತ ಸಂಬೋಧಿಸಿರುವುದನ್ನು ನಾವು ನೋಡಿದ್ದೇವೆ. ಕೃಷ್ಣ ಎಂದರೆ ಕೃಷಿ-ಣಃ -\nಅಂದರೆ ಭೂಮಿಗೆ ಆನಂದವನ್ನು ಕೊಡಲು, ಬಲತುಂಬಲು ಬಂದವ ಎಂದರ್ಥ. ಕೇಶವ ಎಂದರೆ ಕಾ-ಈಶ-ವ.\nಇಲ್ಲಿ 'ಕಾ' ಎಂದರೆ ಸೃಷ್ಟಿಗೆ ಕಾರಣವಾಗಿರುವ ಚತುರ್ಮುಖ ಬ್ರಹ್ಮ; 'ಈಶ' ಎಂದರೆ ಸಂಹಾರಕ್ಕೆ\nಕಾರಣವಾಗಿರುವ ಶಂಕರ; ಕೇಶವ ಎಂದರೆ ಸೃಷ್ಟಿ-ಸಂಹಾರಕ್ಕೆ ಕಾರಣವಾಗಿರುವ ಪರಶಕ್ತಿ.\n\nಇಲ್ಲಿ ಅರ್ಜುನ ಕೃಷ್ಣನನ್ನು 'ಕೇಶವ' ಎಂದು ಸಂಬೋಧಿಸುತ್ತಿರುವುದಕ್ಕೆ ವಿಶೇಷ ಕಾರಣವಿದೆ. \"ಭೂಮಿಗೆ\nಆನಂದವನ್ನು, ತ್ರಾಣವನ್ನು ಕೊಡಲು ಇಳಿದುಬಂದ ಸೃಷ್ಟಿಕರ್ತನಾದ ನೀನೇ ಸಂಹಾರಕಾರಕನಾಗಿ, ಈ\nಯುಗಾಂತದ ಮಹಾಯುದ್ಧದ ಸೂತ್ರದಾರಿಯಾಗಿ ಏಕೆ ನಿಂತೆ? ಏನು ನಿನ್ನ ಉದ್ದೇಶ?'' ಎನ್ನುವುದು ಈ\nವಿಶೇಷಣದ ಹಿಂದಿರುವ ಧ್ವನಿ. ಮಹಾಭಾರತ ಯುದ್ಧದ ಹದಿನೆಂಟನೇ ದಿನ ದ್ವಾಪರಯುಗ ಅಂತ್ಯವಾಗಿ\nಕಲಿಯುಗ ಪ್ರಾರಂಭವಾದದ್ದನ್ನು ಇಲ್ಲಿ ನಾವು ನೆನಪಿಸಿಕೊಳ್ಳಬಹುದು.\n\nಇಲ್ಲಿಂದ ಮುದುವರಿದು ಅರ್ಜುನ ತಾನು ಏಕೆ ಯುದ್ಧ ಮಾಡಬಾರದು ಎನ್ನಲು ಕೆಲವು ಕಾರಣಗಳನ್ನು\nಕೊಡಲಾರಂಭಿಸುತ್ತಾನೆ. \"ನಚ ಶ್ರೇಯಃ ಅನುಪಶ್ಯಾಮಿ ಹತ್ವಾ ಸ್ವಜನಮ್‌ ಆಹವೇ”-'ನಮ್ಮ ಬಂಧುಗಳನ್ನು\nಕೊಲ್ಲುವುದರಿಂದ ನಮ್ಮ ಹೆಸರು ಇತಿಹಾಸದಲ್ಲಿ, ಮುಂದಿನ ಯುಗಗಳಲ್ಲಿ ಪ್ರಶಂಸನೀಯವಾಗಿ ಉಳಿಯುತ್ತದೆ\nಎಂದು ನನಗೆ ಯಾವ ನೆಲೆಯಲ್ಲೂ ಅನಿಸುವುದಿಲ್ಲ' ಎನ್ನುತ್ತಾನೆ ಅರ್ಜುನ.",
  "1.32": "ನ ಕಾಂಕ್ಷೇ ವಿಜಯಮ್‌ ಕೃಷ್ಣ ನ ಚ ರಾಜ್ಯಮ್‌ ಸುಖಾನಿ ಚ |\n\nಕಿಮ್‌ ನಃ ರಾಜ್ಯೇನ ಗೋವಿಂದ ಕಿಮ್‌ ಭೋಗ್ಯೈಃ ಜೀವಿತೇನ ವಾ -. ಕೃಷ್ಣಾ, ನಾನು ಗೆಲುವನ್ನು\nಬಯಸುವುದಿಲ್ಲ; ಇಲ್ಲ ಅರಸೊತ್ತಿಗೆಯನ್ನು ; ಸುಖಗಳನ್ನು ಕೂಡಾ. ಗೋವಿಂದಾ, ನಮಗೆ ದೊರೆತನದಿಂದೇನು?\nಐಷಾರಾಮಗಳಿಂದೇನು ? ಬದುಕಿಯಾದರೂ ಏನು?\n\nಅರ್ಜುನ ಧರ್ಮರಾಯನ ಪರ ಹೋರಾಟಕ್ಕೆ ನಿಂತವ. ಯುದ್ಧವನ್ನು ನಿಲ್ಲಿಸುವುದಾಗಲೀ ಅಥವಾ ನಿರ್ಣಯ\nತೆಗೆದುಕೊಳ್ಳುವುದಾಗಲೀ ಅದು ಕೊನೆಯದಾಗಿ ಧರ್ಮರಾಯನ ವಿವೇಚನೆಯಂತೇ ನಡೆಯಬೇಕು. ಇಲ್ಲಿ\nಅರ್ಜುನ ತಾನೇ ನಿರ್ಣಾಯಕ ಎನ್ನು ವಂತೆ ಮಾತನಾಡುತ್ತಾನೆ. \"ಯಾರಿಗೆ ಬೇಕಾಗಿದೆ ಈ ಗೆಲುವು ಕೃಷ್ಣಾ,\nನನಗೆ ವಿಜಯ ಬೇಕಾಗಿಲ್ಲ, ನಾನು ಗುರುಹಿರಿಯರನ್ನು ಕೊಂದು, ಗೆಲುವನ್ನು ಬಯಸುವುದಿಲ್ಲ\" ಎನ್ನುತ್ತಾನೆ. ಈ\nಶ್ಲೋಕದಲ್ಲಿ ಆತ ಪುನಃ \"ಕೃಷ್ಣ\" ಎಂದು ಸಂಬೋಧಿಸುತ್ತಾನೆ. ಇಲ್ಲಿ \"ಕೃಷ್ಣಃ\" ಎಂದರೆ ಕರ್ಷಣೆ ಮಾಡುವವ. ತನ್ನ\nಸೌಂದರ್ಯದಿಂದ ಆಕರ್ಷಿಸಿ ಉತ್ಕರ್ಷಣೆ ಮಾಡುವವ ಎಂದರ್ಥ. \"ಲೋಕದ ಆಕರ್ಷಣ ಶಕ್ತಿಯಾದ ನೀನು\nನಮ್ಮನ್ನು, ಈ ಹದಿನೆಂಟು ಅಕ್ಷೋಹಿಣಿ ಸೈನ್ಯವನ್ನು ಯುದ್ಧಭೂಮಿಗೇಕೆ ಎಳೆದುತಂದೆ?''' ಎನ್ನುವ\nಭಾವಾರ್ಥದಲ್ಲಿ ಅರ್ಜುನ ಮಾತನಾಡುತ್ತಾನೆ.\n\nಮುಂದುವರಿದು ಅರ್ಜುನ ಹೇಳುತ್ತಾನೆ: \"ನಮಗೆ ಈ ರಾಜ್ಯ ಪಡೆದು ಏನಾಗಬೇಕಾಗಿದೆ? ಈ ರಾಜ್ಯವನ್ನು\nಪಡೆದು, ಭೋಗವನ್ನು ಪಡೆದು ಏನು ಪ್ರಯೋಜನ ಗೋವಿಂದಾ?'' ಎಂದು. ಇಲ್ಲಿ ಅರ್ಜುನ ಭಗವಂತನನ್ನು\n\"ಗೋವಿಂದಃ\" ಎಂದು ಸಂಬೋಧಿಸುತ್ತಾನೆ. ಗೋವಿಂದ ಎಂದರೆ ವೇದಗಳಿಂದ ವಾಚ್ಯನಾದವನು, ವೇದಗಳ\nಸಮಗ್ರ ಅರ್ಥ ತಿಳಿದವನು, ಭೂಮಿಗಿಳಿದು ಬಂದವನು, ಗೋವುಗಳನ್ನು ಕಾಯ್ದವನು ಇತ್ಯಾದಿ. ಕೃಷ್ಣ ಎಷ್ಟೋ\nದುಷ್ಟ ರಾಕ್ಷಸರ ಹಾಗೂ ರಾಜರ ಸಂಹಾರ ಮಾಡಿದವ. ಆದರೆ ಎಲ್ಲಿಯೂ ಸಿಂಹಾಸನವೇರಿ ಅರಸೊತ್ತಿಗೆ\nಮಾಡಿರಲಿಲ್ಲ. ಗೋಪಾಲಕರ ಜೊತೆಗೆ ಸೇರಿ ಗೋವುಗಳನ್ನು ಕಾಯ್ದವ ಆತ. ಇಲ್ಲಿ ಅರ್ಜುನ \"ನಿನ್ನಂತೆ ನನಗೆ\nಯಾವುದೇ ಸಿಂಹಾಸನವೇರುವ ಆಸೆ ಇಲ್ಲ\" ಎನ್ನು ವ ಅರ್ಥದಲ್ಲಿ ಮಾತನಾಡುತ್ತಿದ್ದಾನೆ. \"ಭೂಮಿಗಿಳಿದು ಬಂದ\nನೀನು ನನ್ನನ್ನೇಕೆ ಯುದ್ಧಕ್ಕೆ ಪ್ರೇರೇಪಿಸುತ್ತಿದ್ದಿ? '' ಎನ್ನುವ ಭಾವದಲ್ಲಿ ಆತ ಭಗವಂತನನ್ನು 'ಗೋವಿಂದ' ಎಂದು\nಸಂಬೋಧಿಸಿದ್ದಾನೆ.",
  "1.33": "ಯೇಷಾಮ್ ಅರ್ಥೇ ಕಾಂಕ್ಷಿತಂ ನಃ ರಾಜ್ಯಂ ಭೋಗಾಃ ಸುಖಾನಿ ಚ ।\nತೇ ಇಮೇ ಅವಸ್ಥಿತಾಃ ಯುದ್ಧೇ ಪ್ರಾಣಾನ್ ತ್ಯಕ್ತ್ವಾ ಧನಾನಿ ಚ -- ಯಾರಿಗಾಗಿ ಅರಸೊತ್ತಿಗೆ? ಸುಖ-ಭೋಗಕ್ಕಾಗಿ ಇವರು ಹಣದ ಮತ್ತು ಹೆಣದ ಹಂಗು ತೊರೆದು ಕಾಳಗದ ಕಣದಲ್ಲಿ ನಿಂತಿದ್ದಾರೆ.\n\nಒಂದು ವೇಳೆ ಈ ರಾಜಭೋಗ ಬೇಕಿದ್ದರೆ ಅದು ಯಾರಿಗೋಸ್ಕರ? ನಮ್ಮೆಲ್ಲಾ ಗುರು ಹಿರಿಯರ ಮಧ್ಯೆ ಸಂತೋಷದಿಂದ ನಾವಿರಬೇಕು. ಅವರನ್ನೆಲ್ಲಾ ಕೊಂದು ನಾವೇನು ಸಂತೋಷಪಡುವುದು?",
  "1.34": "ಆಚಾರ್ಯಾಃ ಪಿತರಃ ಪುತ್ರಾಃ ತಥಾ ಏವ ಚ ಪಿತಾಮಹಾಃ |\nಮಾತುಲಾಃ ಶ್ವಶುರಾಃ ಪೌತ್ರಾಃ ಸ್ಯಾಲಾಃ ಸಂಬಂಧಿನಃ ತಥಾ -- ಗುರುಗಳು, ತಂದೆ ತಾಯಿಯಂತಿರುವವರು,\nಮಕ್ಕಳು. ಅಂತೆಯೇ ಅಜ್ಜಂದಿರು, ಮಾವಂದಿರು, ಸೋದರ ಮಾವಂದಿರು, ಮೊಮ್ಮಕ್ಕಳು, ಮೈದುನಂದಿರು\n\nಮತ್ತು ನೆಂಟರಿಷ್ಟರು.\n\nಅರ್ಜುನ ತನ್ನ ಬಂಧುಗಳನ್ನು, ಕುಟುಂಬದ ಸದಸ್ಯರ ಪಟ್ಟಿಯನ್ನು ಕೃಷ್ಣನ ಮುಂದೆ ಹೇಳಿಕೊಳ್ಳುತ್ತಾನೆ.\nಗುರುಗಳು, ಪಿತೃಸಮಾನರು, ಮಕ್ಕಳು, ಅಜ್ಜಂದಿರು, ಮಾವಂದಿರು, ಹೆಣ್ಣು ಕೊಟ್ಟ ಮಾವಂದಿರು, ಮೊಮ್ಮಕ್ಕಳು,\nಹೆಂಡತಿಯ ಅಣ್ಣ-ತಮ್ಮಂದಿರು ಮತ್ತು ನೆಂಟರಿಷ್ಟರು. ಹೀಗೆ ಕೇವಲ ತನ್ನ ಸಂಬಂಧಿಗಳ ಪಟ್ಟಿ ಕೊಡುತ್ತಿರುವ\nಅರ್ಜುನ ತನ್ನ ಸಾಮಾಜಿಕ ಕರ್ತವ್ಯ ಮರೆತು ವೈಯಕ್ತಿಕವಾಗಿ ಮಾತನಾಡುತ್ತಿರುವುದು ಇಲ್ಲಿ ಸ್ಪಷ್ಟವಾಗುತ್ತದೆ.",
  "1.35": "ಏತಾನ್‌ ನ ಹಂತುಮ್‌ ಇಚ್ಛಾಮಿ ಘ್ನತಃ ಅಪಿ ಮಧುಸೂದನ |\nಅಪಿ ತ್ರೈಲೋಕ್ಯ ರಾಜ್ಯಸ್ಯ ಹೇತೋಃ ಕಿಮ್‌ ನು ಮಹೀಕೃತೇ - ಓ ಮಧುಸೂದನಾ, ನನ್ನ ನ್ನು ಕೊಲ್ಲಬಂದರೂ\nನಾನಿವರನ್ನು ಕೊಲ್ಲಬಯಸೆ. ಮೂರು ಲೋಕದ ದೊರೆತನಕ್ಕಾಗಿ ಕೂಡಾ. ಇನ್ನು ಭೂಮಿಯ ಮಾತೇನು?\n\nನನಗೆ ಇವರನ್ನು ಕೊಲ್ಲುವ ಬಯಕೆ ಇಲ್ಲ. ಒಂದು ವೇಳೆ ಅವರು ನನ್ನನ್ನು ಕೊಲ್ಲ ಬಂದರೂ ಕೂಡಾ ನಾನವರನ್ನು\nಕೊಲ್ಲಲಾರೆ. ಇಡೀ ಬ್ರಹ್ಮಾಂಡದ ಒಡೆತನ ಸಿಗುತ್ತದೆ ಎಂದರೂ ಕೂಡಾ ನಾನು ಯುದ್ಧ ಮಾಡಲಾರೆ.\nಅಂತಾದ್ದರಲ್ಲಿ ಈ ತುಂಡು ಭೂಮಿಗಾಗಿ ಏಕೆ ಯುದ್ಧ?\n\nಇಲ್ಲಿ ಅರ್ಜುನ ಶ್ರೀಕೃಷ್ಣನನ್ನು 'ಮಧುಸೂದನ' ಎಂದು ಸಂಬೋಧಿಸಿದ್ದಾನೆ. ಮಧು ಎಂದರೆ ಆನಂದ.\nಮಧುಸೂದನ ಎಂದರೆ. ಆನಂದ ನಾಶಕ... ಧರ್ಮ ಮಾರ್ಗವನ್ನು ಬಿಟ್ಟು, ಅಧರ್ಮಿಯಾಗಿ,\nಮದ(ಆಹಂಕಾರ)ದಿಂದ ಸಾಗುವವರ ಆನಂದವನ್ನು ನಾಶ ಮಾಡಿ, ಸಜ್ಜನರ ಉದ್ಧಾರ ಮಾಡುವ\nಆನಂದರೂಪಿ ಭಗವಂತ ಮಧುಸೂದನ. “ಸಾತ್ವಿಕರಿಗೆ ಆನಂದವನ್ನು ಕೊಟ್ಟು ತಾಮಸಿಗಳ ಆನಂದ ಹರಣ\nಮಾಡುವ ನೀನು ಏನು ಮಾಡಲು ಬಂದವ?\" ಎನ್ನುವ ಧ್ವನಿ ಈ ಸಂಬೋಧನೆಯಲ್ಲಿದೆ. ಇಲ್ಲಿ “ಯುದ್ಧ\nಮಾಡಬೇಕೋ ಬೇಡವೋ ಎನ್ನುವ ಗೊಂದಲ ನನ್ನನ್ನು ಕಾಡುತ್ತಿದೆ” ಎಂದು ಅರ್ಜುನ ತನ್ನ ತುಮುಲವನ್ನು\nಕೃಷ್ಣನಲ್ಲಿ ವ್ಯಕ್ತಪಡಿಸುತ್ತಾನೆ.",
  "1.36": "ನಿಹತ್ಯ ಧಾರ್ತರಾಷ್ಟ್ರಾನ್ ನಃ ಕಾ ಪ್ರೀತಿಃ ಸ್ಯಾದ್ಜನಾರ್ದನ |\nಪಾಪಮ್‌ ಏವ ಆಶ್ರಯೇತ್‌  ಅಸ್ಮಾನ್‌  ಹತ್ವಾ ಏತಾನ್‌ ಆತತಾಯಿನಃ --  ಧಾರ್ತರಾಷ್ಟ್ರರನ್ನು  ಕೊಂದು\nನಮಗಾದರೂ ಏನು ಸುಖವುಂಟು ಜನಾರ್ದನಾ? ಈ ಕುಲಗೇಡಿಗಳನ್ನು ಕೊಂದರೆ ನಮಗೆ ಪಾಪವೇ ತಟ್ಟೀತು.\n\nಒಂದು ವೇಳೆ ಧಾರ್ತರಾಷ್ಟ್ರರನ್ನು ಕೊಂದರೆ ನಮಗೆ ಆನಂದವೇನು? ಅದರಿಂದ ಸಾಯುವ ತನಕ ನಿರಂತರ\nಪಾಪಪ್ರಜ್ಞೆ ನಮ್ಮನ್ನು ಕಾಡಬಹುದು. ಇವರನ್ನು ಕೊಂದು ಪಾಪಪ್ರಜ್ಞೆಯಿಂದ ಬದುಕಬೇಕೇ ಹೊರತು ಇನ್ನೇನೂ\nಲಾಭವಿಲ್ಲ-ಇದು ಅರ್ಜುನನ ವಾದ.\n\nಈ ಶ್ಲೋಕದಲ್ಲಿ ಅರ್ಜುನ \"ಆತತಾಯಿ\" ಎನ್ನುವ ಪದವನ್ನು ಬಳಸಿದ್ದಾನೆ. ಆತತಾಯಿ ಎಂದರೆ ಇನ್ನೊಬ್ಬರ\nಮನೆಗೆ ಬೆಂಕಿ ಹಾಕುವವ; ಇನ್ನೊಬ್ಬರ ಆಹಾರಕ್ಕೆ ವಿಷ ಬೆರೆಸಿ ಕೊಡುವವ; ಇನ್ನೊಬ್ಬರ ಆಸ್ತಿಯನ್ನು\nಲಪಟಾಯಿಸುವವ; ಪರ ಸ್ತ್ರೀಯರ ಮೇಲೆ ಕೈ ಹಾಕುವವ ಇತ್ಯಾದಿ. ಶಾಸ್ತ್ರ 'ಆತತಾಯಿನರನ್ನು' ಕಂಡಲ್ಲಿ\nಹೊಡೆದು ಸಾಯಿಸು ಎನ್ನುತ್ತದೆ. ಇಲ್ಲಿ ದುರ್ಯೋಧನ ಮೇಲಿನ ಎಲ್ಲಾ ಕೆಟ್ಟ ಕೆಲಸವನ್ನೂ ಮಾಡಿದ್ದ. ಭೀಮನಿಗೆ\nವಿಷ ಸೇರಿಸಿ ಕೊಟ್ಟಿದ್ದ, ದ್ರೌಪದಿ ವಸ್ತ್ರಾಪಹರಣ ಮಾಡಿದ್ದ, ಪಾಂಡವರಿದ್ದ ಅರಗಿನ ಮನೆಗೆ ಬೆಂಕಿ ಇಟ್ಟಿದ್ದ. ಆದರೆ\nಇಲ್ಲಿ ಅರ್ಜುನನಿಗೆ ಬಂಧು ಪ್ರೇಮ ಎಲ್ಲಿಯವರೆಗೆ ಕಾಡುತ್ತಿದೆ. ಎಂದರೆ ಆತ     “ಇವರೆಲ್ಲರೂ\nಆತತಾಯಿನರಾದರೂ ಕೂಡಾ, ನನ್ನ ದೊಡ್ಡಪ್ಪನ ಮಕ್ಕಳಲ್ಲವೇ?” ಎಂದು ಕೃಷ್ಣನಲ್ಲಿ ಪರಿತಪಿಸುತ್ತಾನೆ.\n\nಈ ಶ್ಲೋಕದಲ್ಲಿ ಅರ್ಜುನ ಶ್ರೀಕೃಷ್ಣನನ್ನು 'ಜನಾರ್ದನ' ಎಂದು ಸಂಬೋಧಿಸಿದ್ದಾನೆ. ಜನಾರ್ದನ ಎಂದರೆ\nದುರ್ಜನ ಸಂಹಾರಕ ಹಾಗೂ ಸಜ್ಜನರಿಗೆ ಮುಂದೆ ಹುಟ್ಟಿಲ್ಲದ ಮೋಕ್ಷಪ್ರದವಾದ ಸಾವನ್ನು ಕೊಡುವವ.\n''ಮೋಕ್ಷಪ್ರದನಾದ ನೀನು ಮತ್ತೆ ಪುನಃ ಈ ಹುಟ್ಟು-ಸಾವಿನ ಚಕ್ರದಲ್ಲಿ ಬರುವ ಈ ಯುದ್ಧದಲ್ಲಿ ನಮ್ಮನ್ನು ಏಕೆ\nತೊಡಗಿಸುತ್ತಿರುವೆ? ಯುದ್ಧ ಎಂದೂ ಮೋಕ್ಷಪ್ರದವಲ್ಲ, ಅದು ಸೇಡು-ದ್ವೇಷದಿಂದ ಕೂಡಿರುತ್ತದೆ. ಹಾಗಿರುವಾಗ\nಈ ಯುದ್ಧ ಏಕೆ?” ಎನ್ನುವುದು ಈ ಸಂಬೋಧನೆಯ ಹಿಂದಿರುವ ಧ್ವನಿ.",
  "1.37": "ತಸ್ಮಾತ್‌ ನ ಅರ್ಹಾ ವಯಮ್‌ ಹಂತುಮ್‌ ಧಾರ್ತರಾಷ್ಟ್ರಾನ್‌ ಸ್ವ ಬಾಂಧವಾನ್‌ |\nಸ್ವ ಜನಮ್‌ ಹಿ ಕಥಮ್‌ ಹತ್ವಾ ಸುಖಿನಃ ಸ್ಯಾಮ ಮಾಧವಾ-ಆದ್ದರಿಂದ ನಮ್ಮ ಅನುಬಂಧಿಗಳಾದ\n\nಧಾರ್ತರಾಷ್ಟ್ರರನ್ನು ನಾವು. ಕೊಲ್ಲುವುದು. ತರವಲ್ಲ. ನಮ್ಮ ಮಂದಿಯನ್ನು ಕೊಂದು ನಾವು ಹೇಗೆ\nಸುಖಿಗಳಾದೇವು ಮಾಧವಾ?\n\nಧಾರ್ತರಾಷ್ಟ್ರರು ನಮ್ಮ ಸಹೋದರರು. ಅವರನ್ನು ಕೊಲ್ಲುವುದು ತರವಲ್ಲ. ನಮ್ಮ ಮಂದಿಯನ್ನೇ ನಾವು\nಕೊಂದು ಹೇಗೆ ನಾವು ಸುಖಿಗಳಾದೇವು? ಇದು ಅರ್ಜುನನ ಪ್ರಶ್ನೆ ಸೂಕ್ಷ್ಮವಾಗಿ ಗಮನಿಸಿದಾಗ ಇಲ್ಲಿ ಅರ್ಜುನ\nತಾನು ಪ್ರಜಾಪಾಲಕ, ಧರ್ಮವನ್ನು ರಕ್ಷಿಸುವುದು ನನ್ನ ಕರ್ತವ್ಯ ಎನ್ನುವುದನ್ನು ಪೂರ್ಣ ಮರೆತು\nಮಾತನಾಡುತ್ತಿರುವುದು ಸ್ಪಷ್ಟವಾಗಿ ಕಾಣುತ್ತದೆ.\n\nಇಲ್ಲಿ ಅರ್ಜುನ ಕೃಷ್ಣನನ್ನು 'ಮಾಧವ' ಎಂದು ಸಂಬೋಧಿಸುತ್ತಾನೆ. 'ಮಾ' ಅಂದರೆ ಮಾತೆ ಲಕ್ಷ್ಮಿ. ಆದ್ದರಿಂದ\nಮಾಧವ ಅಂದರೆ ಲಕ್ಷ್ಮೀಪತಿ ಭಗವಂತ. ಇನ್ನು 'ಮಾ' ಅಂದರೆ ಜ್ಞಾನ ಕೂಡಾ ಹೌದು. ಭಗವಂತ ಜ್ಞಾನದ\nಒಡೆಯ, ಆದ್ದರಿಂದ ಆತ ಮಾಧವ. ಶ್ರೀಕೃಷ್ಣ ಮಧುವಂಶದಲ್ಲಿ ಹುಟ್ಟಿ ಬಂದದ್ದರಿಂದ ಆತನನ್ನು ಮಾಧವ ಎಂದೂ\nಕರೆಯುತ್ತಾರೆ. ವೇದದಲ್ಲಿ ಮಾತೃ ಎನ್ನುವ ಪದವನ್ನು ಮಾತು ಅಥವಾ ವಾಜ್ಮಯ ಎನ್ನುವ ಅರ್ಥದಲ್ಲಿ\nಉಪಯೋಗಿಸಿದ್ದಾರೆ. ಸಮಸ್ತ ವೈದಿಕ ವಾಜ್ಮಯ ಪ್ರತಿಪಾದ್ಯನಾದ ಭಗವಂತ ಮಾಧವ. ಅರ್ಜುನ\nಶ್ರೀಕೃಷ್ಣನನ್ನು ಈ ರೀತಿ ಸಂಬೋಧಿಸಲು ಕಾರಣವಿದೆ. ಕೃಷ್ಣ ಬರಿಯ ಸೋದರಮಾವನ ಮಗನಲ್ಲ,\nಇನ್ಯಾವುದೋ ಅತಿಮಾನುಷ ಶಕ್ತಿ ಎನ್ನುವ ಎಚ್ಚರ ಆತನಲ್ಲಿತ್ತು. ಆ ಕಾರಣದಿಂದ ಆತ ಒಂದೊಂದು ಕಡೆ\nಒಂದೊಂದು ರೀತಿ ಭಗವಂತನ ಆ ಅತಿಮಾನುಷ ಶಕ್ತಿಯನ್ನು ನೆನಪಿಸಿಕೊಂಡಿದ್ದಾನೆ. \"ನೀನು ಈ ಜಗತ್ತಿನ\nಆದಿಶಕ್ತಿಯೆಂದು ನನಗೆ ತಿಳಿದಿದೆ. ಆದರೂ ಕೂಡಾ ಈ ಒಡಂಬಡಿಕೆಯಲ್ಲಿ ಏಕೆ ಮೂಕ ಪ್ರೇಕ್ಷಕನಾಗಿ\nಕುಳಿತಿದ್ದೀಯ”- ಎನ್ನುವುದು ಆತನ ಈ ಸಂಬೋಧನೆಯ ತಾತ್ಪರ್ಯ.\n\nಇದು ಎಷ್ಟು ವಿಚಿತ್ರ. ಭಗವಂತನ ಜೊತೆಗಿದ್ದು, ಕೃಷ್ಣನನ್ನು ಅತಿಮಾನುಷ ಶಕ್ತಿ ಎಂದು ತಿಳಿದ ಮಹಾಜ್ಞಾನಿ\nಅರ್ಜುನ, ಪ್ರತೀ ಕ್ಷಣದಲ್ಲಿ ಗೊಂದಲಕ್ಕೊಳಗಾಗುತ್ತಾನೆ. ಹೀಗಿರುವಾಗ ನಮ್ಮ ನಿಮ್ಮ ಪಾಡೇನು? ಇದು ವಿಚಿತ್ರ\nಮಾಯೆ. ಮಣ್ಣು ತಿಂದ ಶ್ರೀಕೃಷ್ಣನ ಬಾಯಿಯಲ್ಲಿ ಭಗವಂತನ ವಿಶ್ವರೂಪವನ್ನು ಕಂಡ ಮೇಲೂ ಯಶೋದೆ,\nಕೃಷ್ಣನನ್ನು ಶಿಕ್ಷಿಸಲು ಮುಂದಾಗುತ್ತಾಳೆ. ಇದು 'ನನ್ನ ಮಗು' ಎನ್ನುವ ಮಮತೆಯ ಮಾಯೆಯಲ್ಲಿರುತ್ತಾಳೆ. ಇಲ್ಲಿ\nಅರ್ಜುನನ ಸ್ಥಿತಿ ಕೂಡಾ ಇದೇ.",
  "1.38": "ಯದಿ ಅಪಿ ಏತೇ ನ ಪಶ್ಯಂತಿ ಲೋಭ ಉಪಹತ ಚೇತಸಃ।\nಕುಲಕ್ಷಯ ಕೃತಮ್‌ ದೋಷಮ್‌ ಮಿತ್ರದ್ರೋಹೇ ಚ ಪಾತಕಮ್‌- -ಇವರೆಲ್ಲರ ಹೃದಯ ಲೋಭದ ವಶವಾಗಿದೆ.\nಕುಲದ ಅಳಿವಿನಿಂದಾಗುವ ಮತ್ತು ಮಿತ್ರ ದ್ರೋಹದಿಂದಾಗುವ ಪಾತಕವನ್ನು ಇವರು ಕಾಣುತ್ತಿಲ್ಲ.\n\nದುಡ್ಡಿನ ಆಸೆಯಿಂದ, ಲೋಭದಿಂದ ಕುರುಡಾಗಿ ಅವರ ಮನಸ್ಸು ಯೋಚಿಸುವ ಶಕ್ತಿಯನ್ನು ಕಳೆದುಕೊಂಡಿದೆ.\nಇದರಿಂದ ಕುಲಕ್ಷಯವಾಗುತ್ತದೆ. ಇಡೀ ಭರತವಂಶ ನಿರ್ವಂಶವಾಗುತ್ತದೆ. ಬಂಧುಗಳಾದ ನಾವು\nಒಬ್ಬರಿಗೊಬ್ಬರು ಮಿತ್ರರಂತೆ ಆತ್ಮೀಯತೆಯಿಂದ ಬದುಕಬೇಕಿತ್ತು. ಆದರೆ ಒಬ್ಬರನೊಬ್ಬರು ದ್ವೇಷಿಸುತ್ತಿದ್ದೇವೆ.\nಇದು ದ್ರೋಹ.\n\nಇಲ್ಲಿ 'ಮಿತ್ರ' ಎನ್ನುವ ಪದ ಬಳಕೆಯಾಗಿದೆ. ಯಾರು ನಿಜವಾದ ಮಿತ್ರ? ನಮಗೆ ಯಾವಾಗ ಆಪತ್ತು ಬಂದೀತು\nಎಂದು ನಮಗಿಂತ ಮೊದಲೇ ಊಹಿಸಿ, ಪೂರ್ವಭಾವಿಯಾಗಿ ಯಾವುದೇ ಪ್ರತಿಫಲವನ್ನು ಅಪೇಕ್ಷಿಸದೇ, ಜೀವಕ್ಕೆ\nಜೀವ ಕೊಡುವವನು 'ಮಿತ್ರ'.",
  "1.39": "ಕಥಮ್‌ ನ ಜ್ಞೇಯಮ್‌ ಅಸ್ಮಾಭಿಃ ಪಾಪಾತ್‌ ಅಸ್ಮಾತ್‌ ನಿವರ್ತಿತುಮ್‌ |\nಕುಲಕ್ಷಯ ಕೃತಮ್‌ ದೋಷಮ್‌ ಪ್ರಪಶ್ಯದ್ಧಿ ಜನಾರ್ದನ- ಓ ಜನಾರ್ದನಾ, ಕುಲದ ಅಳಿವಿನಿಂದಾಗುವ ಕೇಡನ್ನು\nಮುಂಗಾಣಬಲ್ಲ ನಾವು ಇಂತಹ ತಪ್ಪಿನಿಂದ ದೂರವಿರಬೇಕು ಎಂದರಿಯದಿದ್ದರೆ ಹೇಗೆ?\n\nಇಂತಹ ಮಹಾಪಾಪವನ್ನು ಮಾಡಬಾರದು ಎಂದು ನಾವು ತಿಳಿದುಕೊಳ್ಳದಿದ್ದರೆ, ದುರ್ಯೋಧನನಿಗೂ ನಮಗೂ\nಇರುವ ವ್ಯತ್ಯಾಸವಾದರೂ ಏನು? ಹುಟ್ಟು ಸಾವುಗಳ ಬಂಧದಿಂದ ಪಾರುಮಾಡುವ ಓ ಜನಾರ್ದನನೇ, ಒಂದು\nಕುಲವನ್ನು ನಾಶ ಮಾಡುವಂತಹ ದೋಷ ಸ್ಪಷ್ಟವಾಗಿ ನನ್ನ ಕಣ್ಣಿಗೆ ಕಾಣುತ್ತಿದೆ. ಯುದ್ಧೋತ್ತರ ಭಾರತದ ಚಿತ್ರ\nನನ್ನ ಕಣ್ಣಿಗೆ ಕಟ್ಟುತ್ತಿದೆ. ಯುದ್ಧದಿಂದಾಗುವ ಅನಿಷ್ಟ ಗೊತ್ತಿದ್ದೂ ಕೂಡಾ, ಯುದ್ಧಕ್ಕೆ ಕಾಲು ಕೆದಕುವ ಬುದ್ಧಿಯನ್ನು\nನಾವು ತೋರಿಸಿದರೆ ದುರ್ಯೋಧನನಂತೆ ನಾವು ಕೀಳು ಮಟ್ಟಕ್ಕಿಳಿದಂತಾಗುವುದಿಲ್ಲವೇ? ಇದು ಅರ್ಜುನನ ಪ್ರಶ್ನೆ.",
  "1.40": "ಕುಲಕ್ಷಯೇ ಪ್ರಣಶ್ಯಂತಿ ಕುಲ ಧರ್ಮಾಃ ಸನಾತನಾಃ |\nಧರ್ಮೇ ನಷ್ಟೇ ಕುಲಮ್‌ ಕೃತ್ಸ ಮ್‌ ಅಧರ್ಮಃ ಅಭಿಭವತಿ ಉತ - ಕುಲ ಕುಸಿದಾಗ ಅಳಿವಿರದ ಕುಲಧರ್ಮಗಳು\nಕಣ್ಮರೆಯಾಗುತ್ತವೆ. ಧರ್ಮ ಮರೆಯಾದರೆ ಇಡಿಯ ಕುಲವನ್ನು ಅಧರ್ಮ ಆಕ್ರಮಿಸಿಬಿಡುತ್ತದೆ.\n\nಯುದ್ಧದಿಂದಾಗುವ ದೊಡ್ಡ ಸಮಸ್ಯೆ ಎಂದರೆ \"ಕುಲಧರ್ಮ\" ನಾಶ. ಈ ಶ್ಲೋಕದಲ್ಲಿ ಅರ್ಜುನ ಧರ್ಮದ\nಕುರಿತಾದ ಕೆಲವು ಪದಗಳನ್ನು ಬಳಸುತ್ತಾನೆ. ಜಾತಿಧರ್ಮ, ಕುಲಧರ್ಮ, ಸನಾತನಧರ್ಮ ಇತ್ಯಾದಿ ಶಬ್ದಗಳು\nಅರ್ಥವಾಗಬೇಕಾದರೆ ಮೊದಲು ನಾವು ಧರ್ಮ ಅಂದರೆ ಏನು? ಅದರಲ್ಲಿ ಎಷ್ಟು ವಿಧ? ಎನ್ನುವುದನ್ನು\nತಿಳಿದುಕೊಳ್ಳಬೇಕು.\n\nಸಾಮಾನ್ಯವಾಗಿ ಜಾತಿಧರ್ಮ ಎಂದಾಗ ನಮಗೆ ಕಾಣುವುದು ಬ್ರಾಹ್ಮಣ-ಕ್ಷತ್ರಿಯ-ವೈಶ್ಯ-ಶೂದ್ರ ಎನ್ನುವ ಜಾತಿ.\nಇನ್ನು ಕುಲಧರ್ಮ ಎಂದಾಗ ಒಂದು ಮನೆತನದ ಮೂಲ ಕೆಲಸ. ಬಡಗಿ, ಕಮ್ಮಾರ, ಚಮ್ಮಾರ ಇತ್ಯಾದಿ. ಆದರೆ\nಇಲ್ಲಿ ಹೇಳುವುದು ಇದನ್ನಲ್ಲ. ಕುಲಧರ್ಮ ಎಂದರೆ ಸಮಾಜಧರ್ಮ(convention of society); ಜಾತಿಧರ್ಮ\n\nಎಂದರೆ ಹುಟ್ಟುಗುಣದಿಂದ ಬಂದ ಮನುಷ್ಯನ ಸಹಜ ವೈಯಕ್ತಿಕ ಧರ್ಮ. ಈ ಎರಡು ಧರ್ಮದ ಆಅಚೆಗೆ\nಸನಾತನಧರ್ಮ. ಅದು ಶಾಶ್ವತಧರ್ಮ. ಎಲ್ಲಾ ಕಾಲದಲ್ಲೂ, ಎಲ್ಲಾ ದೇಶದಲ್ಲೂ ಸನಾತನಧರ್ಮ ಬದಲಾಗದು.\nವ್ಯಕ್ತಿಧರ್ಮ ವ್ಯಕ್ತಿಗಳ ನಡುವೆ ಬದಲಾಗುತ್ತದೆ. ಸಮಾಜಧರ್ಮ ಕಾಲಕ್ಕನುಗುಣವಾಗಿ, ದೇಶಕ್ಕನುಗುಣವಾಗಿ\nಬದಲಾಗುತ್ತದೆ.\n\nಜಾತಿಧರ್ಮ ಎಂದರೆ ನಮ್ಮ ಸಹಜವಾದ ಹುಟ್ಟುಗುಣ (ಸ್ವಭಾವ). ಪ್ರತಿಯೊಂದು ಜೀವಕ್ಕೂ ಅದರದ್ದೇ ಆದ\nಸ್ವಭಾವವಿದೆ, ಆದರೆ ಪತ್ತೆ ಹಚ್ಚುವುದು ಕಷ್ಟ. ಏಕೆಂದರೆ ಅದರ ಮೇಲಿರುವ ಎರಡು ಆವರಣ. ಒಂದು\nಅನುವಂಶೀಯ ಹಾಗೂ ಇನ್ನೊಂದು ಬೆಳೆದ ವಾತಾವರಣದ ಪ್ರಭಾವ. ಪರಿಸರದ ಶಿಶುವಾದ ಮಾನವ\nಅನುವಂಶೀಯವಾಗಿ ಹರಿದುಬರುವ ಗುಣಗಳು ಹಾಗೂ ಪರಿಸರದ ಪ್ರಭಾವದಲ್ಲಿ ಬದುಕುತ್ತಾನೆ. ಇವು ನೈಜ\nಸ್ವಭಾವವನ್ನು ಮುಚ್ಚಿಬಿಡುತ್ತವೆ.\n\nಸಮಾಜಧರ್ಮ: ನಾವು ಇನ್ನೊಬ್ಬರ ನೆರವಿಲ್ಲದೆ ಏಕಾಂಗಿಯಾಗಿ ಬದುಕುವವರಲ್ಲ. ಆದ್ದರಿಂದ ಸಂಘಟನೆಗೆ\nಒಂದು ಪ್ರತ್ಯೇಕಧರ್ಮ. ವ್ಯಕ್ತಿ ಧರ್ಮವನ್ನು(ವೈಯಕ್ತಿಕ ಅಭಿರುಚಿಯನ್ನು) ಸಮಾಜಧರ್ಮಕ್ಕೋಸ್ಕರ\nಬದಲಿಸಿಕೊಳ್ಳಬೇಕಾಗುತ್ತದೆ(ಉದಾಹರಣೆಗೆ: ಜೋರಾಗಿ ಮಾತನಾಡುವುದು ನನ್ನ ವೈಯಕ್ತಿಕಧರ್ಮ. ಆದರೆ\nಆಸ್ಪತ್ರೆಯಲ್ಲಿ ನಿಶ್ಯಬ್ಧ ಕಾಪಾಡುವುದು ಸಮಾಜಧರ್ಮ). ಸಮಾಜಧರ್ಮ ಸಮಾಜ ಬದಲಾದಂತೆ,\nಸಮಾಜಕ್ಕನುಗುಣವಾಗಿ ಬದಲಾಗುತ್ತದೆ. ಉದಾಹರಣೆಗೆ ವಿವಾಹಧರ್ಮ. ಇಂತಹ ವಯಸ್ಸಿಗೆ\nಮದುವೆಯಾಗಬೇಕು ಎನ್ನುವುದು ಕಾಲಕ್ಕನುಗುಣವಾಗಿ ಬದಲಾಗುತ್ತದೆ. ವೇದಕಾಲದಲ್ಲಿ ಹೆಣ್ಣು ಮಕ್ಕಳ\nಬಾಲ್ಯವಿವಾಹ ಪದ್ಧತಿ ಜಾರಿಯಲ್ಲಿತ್ತು. ಕಾರಣವೇನೆಂದರೆ ಆಗ ಗುರುಕುಲ ಪದ್ಧತಿ ಇದ್ದು ಗಂಡುಮಕ್ಕಳು ತಮ್ಮ\nಎಂಟನೇ ವಯಸ್ಸಿನಿಂದ ಇಪ್ಪತ್ತನೇ ವಯಸ್ಸಿನ ತನಕ ಗುರುಕುಲದಲ್ಲಿ ವಿಧ್ಯಾಭ್ಯಾಸ ಮಾಡಿ ನಂತರ ಮನೆಗೆ\nಹಿಂತಿರುಗುತ್ತಿದ್ದರು(ಇದನ್ನು ಸಮಾವರ್ತನ ಎನ್ನುತ್ತಾರೆ). ಹಾಗೆ ಕಲಿತು ಬಂದ ಹುಡುಗನಿಗೆ ಎಂಟು ವರ್ಷದ\nಹೆಣ್ಣನ್ನು ಮದುವೆ ಮಾಡಿಸುತ್ತಿದ್ದರು. ಆಕೆ ಆತನ ಶಿಷ್ಯೆಯಾಗಿ ವಿಧ್ಯಾಭಾಸ ಕಲಿತು ವಯಸ್ಸಿಗೆ ಬಂದನಂತರ\nಸಂಸಾರ ಮಾಡುತ್ತಿದ್ದಳು. ಇದರಿಂದ ಆಕೆಗೆ ಗಂಡನನ್ನು ಅರಿಯುವ, ಗಂಡನ ಮನೆಯ ವಾತಾವರಣಕ್ಕೆ\nಹೊಂದಿಕೊಳ್ಳುವ ಗುಣ ಬರುತ್ತಿತ್ತು. ಕ್ರಮೇಣ ಗುರುಕುಲ ಪದ್ಧತಿ ಕೊನೆಗೊಂಡಾಗ, ಈ ಬಾಲ್ಯವಿವಾಹ ಕೂಡಾ\nಕೊನೆಗೊಂಡಿತು. ರಾಮಾಯಣ ಮಹಾಭಾರತ ಕಾಲದಲ್ಲಿ ಬಾಲ್ಯವಿವಾಹ ಇರಲಿಲ್ಲ. ನಂತರ ಇತ್ತೀಚೆಗೆ\nಸುಮಾರು ಒಂದು ಸಾವಿರ ವರ್ಷದ ಹಿಂದೆ ವಿದೇಶಿ ಆಕ್ರಮಣವಾದಾಗ ಹೆಣ್ಣು ಮಕ್ಕಳನ್ನು ಶಾಲೆಗೆ ಕಳುಹಿಸದೇ\nಬೇಗ ಮದುವೆ ಮಾಡಿಸಲಾರಂಭಿಸಿದರು. ಇದು ಸಾಮಾಜಿಕ ಒತ್ತಡದಿಂದ ಆದ ಬದಲಾವಣೆ. ಹೀಗೆ\nಸಮಾಜಧರ್ಮ ಸಮಯಕ್ಕನುಗುಣವಾಗಿ, ಸಮಾಜಕ್ಕನುಗುಣವಾಗಿ ಬದಲಾಗುತ್ತದೆ.\n\nಸನಾತನಧರ್ಮ: ಇದು ಎಲ್ಲಾ ಕಾಲದಲ್ಲೂ, ಎಲ್ಲಾ ಸ್ಥಿತಿಯಲ್ಲೂ ಎಂದೂ ಬದಲಾಗದ ಧರ್ಮ. ವೇದ ಹೇಳುವುದು\nಸನಾತನ ಧರ್ಮವನ್ನು. ಉದಾಹರಣೆಗೆ: ಪ್ರಾಮಾಣಿಕವಾಗಿ ಬದುಕಬೇಕು, ಇನ್ನೊಬ್ಬರ ಸೊತ್ತನ್ನು\nಕದಿಯಬಾರದು, ಸತ್ಯವನ್ನು ಹೇಳಬೇಕು, ದೇವರನ್ನು ನಂಬಿ ನಡೆಯಬೇಕು, ಇತ್ಯಾದಿ. ಇದು ಶಾಶ್ವತ ಧರ್ಮ.\nಎಲ್ಲಾ ದೇಶ-ಕಾಲದಲ್ಲೂ ಬದಲಾಗದ ಧರ್ಮ.\n\nಸನಾತನ ಧರ್ಮಕ್ಕನುಗುಣವಾಗಿ ಸಾಮಾಜಿಕ ಧರ್ಮವನ್ನು ಹೊಂದಿಸಿಕೊಳ್ಳಬೇಕು. ಜಾತಿಧರ್ಮವನ್ನು\nಸಮಾಜಧರ್ಮಕ್ಕನುಗುಣವಾಗಿ ಹೊಂದಿಸಿಕೊಳ್ಳಬೇಕು. ಒಂದು ವಸ್ತುವಿನ ಅಸಾಧಾರಣ ಗುಣ(ಲಕ್ಷಣ)\n\nಅದರ ಧರ್ಮ. ಉದಾಹರಣೆಗೆ: ನೋಡುವುದು ಕಣ್ಣಿನ ಧರ್ಮ, ಕೇಳುವುದು ಕಿವಿಯ ಧರ್ಮ. ಆದರೆ ಯಾವುದು\nಧರ್ಮವೋ ಅದೇ ಅಧರ್ಮವಾಗಬಹುದು. ನೋಡಬಾರದ್ದನ್ನು ನೋಡುವುದು ಅಧರ್ಮ! ನೋಡುವುದಕ್ಕೆ ಒಂದು\nಸೀಮೆ ಇದೆ. ಅದನ್ನು ದಾಟಿದಾಗ ಧರ್ಮವೇ ಅಧರ್ಮವಾಗುತ್ತದೆ.\n\nಇಲ್ಲಿ ಅರ್ಜುನ ಹೇಳುತ್ತಾನೆ: “ಕುಲಕ್ಷಯವಾದಾಗ ಸಮಾಜ ಧರ್ಮವನ್ನು ನಡೆಸಬೇಕಾದ ನ್ಯಾಯಾಂಗ ವ್ಯವಸ್ಥೆ\nನಾಶವಾಗಿ ಸಮಾಜ ಧರ್ಮ ನಾಶವಾಗುತ್ತದೆ. ಸಾಮಾಜಿಕ ವ್ಯವಸ್ತೆ ಕುಸಿದು ಬೀಳುತ್ತದೆ. ಇಡೀ ಸಮಾಜ\nಅಧರ್ಮದಲ್ಲಿ ಮುಳುಗುತ್ತದೆ. ಇದು ಯುದ್ಧ ಮಾಡುವುದರಿಂದ ಸಮಾಜಕ್ಕೆ ನಾವು ಕೊಡುವ ಕಾಣಿಕೆ” ಎಂದು.",
  "1.41": "ಅಧರ್ಮ ಅಭಿಭವಾತ್‌ ಕೃಷ್ಣ ಪ್ರದುಷ್ಯಂತಿ ಕುಲಸ್ತ್ರಿಯಃ\nಸ್ತ್ರೀಷು ದುಷ್ಟಾಸು ವಾರ್ಷ್ಣೇಯ ಜಾಯತೇ ವರ್ಣಸಂಕರಃ -ಓ ವಾರ್ಷ್ಣೇಯಾ, ಅಧರ್ಮದ ಆಕ್ರಮಣದಿಂದ\n\nಸಮಾಜದಲ್ಲಿ ಹೆಣ್ಣು ಮಕ್ಕಳು ದಾರಿಗೆಡುತ್ತಾರೆ. ಅದರಿಂದ ಸಮಾಜ ವರ್ಣಸಂಕರಕ್ಕೀಡಾಗುತ್ತದೆ.\n\nಯುದ್ಧವಾದರೆ ಅದರಿಂದ ಯುವಕರೆಲ್ಲರೂ ಸಾಯುತ್ತಾರೆ. ಅಧರ್ಮ ಸಮಾಜವನ್ನು ಆಕ್ರಮಿಸುತ್ತದೆ.\nಯುವಕರಿಲ್ಲದ ಸಮಾಜ ಸೃಷ್ಟಿಯಾಗುತ್ತದೆ. ಸಾಮಾಜಿಕವಾಗಿ ಸ್ತ್ರೀಗೆ ಭದ್ರತೆ ಇಲ್ಲದಂತಾಗುತ್ತದೆ. ಅದರ\nಪರಿಣಾಮ ಆಕೆಯ ಮುಗ್ಧತೆಯ ದುರುಪಯೋಗ. ಅದರಿಂದ ಸಮಾಜದಲ್ಲಿ ವರ್ಣಸಂಕರ ಉಂಟಾಗುತ್ತದೆ\nಎನ್ನುತ್ತಾನೆ ಅರ್ಜುನ.\n\nಇಲ್ಲಿ ವರ್ಣಸಂಕರ ಎಂದರೆ ಜೀವದ ಬಣ್ಣ ಅಥವಾ ಸ್ವಭಾವ ಹಾಳಾಗುವುದು. ಹೆಣ್ಣಿಗೆ ಬಲವಂತವಾಗಿ ಆಕೆಯ\nಮನಸ್ಸಿಗೆ ವಿರುದ್ಧವಾಗಿ ಉಚ್ಚ ಶಿಕ್ಷಣ ಕೊಡಬಾರದು ಎಂದು ಶಾಸ್ತ್ರಗಳಲ್ಲಿ ಉಲ್ಲೇಖವಿದೆ. ಕಾರಣ ಅದರಿಂದ\nಆಕೆಯ ಗರ್ಭಕೋಶದ ಮೇಲೆ ಪರಿಣಾಮವಾಗುತ್ತದೆ. ಅದರ ಪರಿಣಾಮ ಹುಟ್ಟುವ ಮಗುವಿನ ಮೇಲೆ ಆಗುತ್ತದೆ.\nಹೆಣ್ಣು ತನಗಿಷ್ಟವಿಲ್ಲದೇ ತನ್ನನ್ನು ತೊಡಗಿಸಿಕೊಂಡಾಗ; ಅನೇಕ ಪುರುಷರ ಸಂಗ ಮಾಡುವುದರಿಂದ; ಮುಂದಿನ\nಸಂತಾನದ ಮೇಲೆ ಘೋರ ಪರಿಣಾಮವುಂಟಾಗುತ್ತದೆ. ಯಾರ ಮಾತನ್ನೂ ಕೇಳದ, ಯಾರ ನಿಯಮಕ್ಕೂ ಬಗ್ಗದ\nವಿಕ್ಷಿಪ್ತ ಸಂತತಿ ಹುಟ್ಟುವ ಸಾಧ್ಯತೆ ಇದೆ. ಇದು ಇಲ್ಲಿ ಅರ್ಜುನ ಹೇಳುತ್ತಿರುವ ವರ್ಣಸಂಕರ.\n\nಇಲ್ಲಿ ಅರ್ಜುನ ಕೃಷ್ಣನನ್ನು 'ವಾರ್ಷ್ಣೇಯ' ಎಂದು ಸಂಬೋಧಿಸಿದ್ದಾನೆ. ಯಾದವ ಮನೆತನದ ಹಿರಿಯ ರಾಜ ವೃಷ್ಣಿ.\nಆ ವಂಶದಲ್ಲಿ ಅವತರಿಸಿದ ಕೃಷ್ಣ ವಾರ್ಷ್ಣೇಯ. ಈ ಹೆಸರಿನ ಬಗ್ಗೆ ವೇದದಲ್ಲಿ ಉಲ್ಲೇಖವಿದೆ. ಬಯಸಿದ\nಅಭೀಷ್ಟವನ್ನು ಕೊಡುವ ಹಿರಿಯ ಶಕ್ತಿಗಳಾದ ದೇವತೆಗಳ ಒಡೆಯ ಭಗವಂತ ವಾರ್ಷ್ಣೇಯ. “ಎಲ್ಲರ ಅಭೀಷ್ಟವನ್ನು\nಈಡೇರಿಸುವ, ಧರ್ಮ ಸಂಸ್ಥಾಪನೆಗಾಗಿ ಇಳಿದುಬಂದ ನೀನು, ಏಕೆ ಈ ಯುದ್ಧವನ್ನು ತಡೆಯುತ್ತಿಲ್ಲ” ಎನ್ನುವ ಧ್ವನಿ\nಅರ್ಜುನನ ಈ ಸಂಬೋಧನೆಯಲ್ಲಿದೆ.",
  "1.42": "ಸಂಕರಃ ನರಕಾಯ ಏವ ಕುಲಘ್ನಾನಾಮ್‌ ಕುಲಸ್ಯ ಚ |\nಪತಂತಿ ಪಿತರಃ ಹಿ ಏಷಾಮ್‌ ಲುಪ್ತ ಪಿಂಡ ಉದಕ ಕ್ರಿಯಾಃ -ಬಣ್ಣಗೇಡು ಕುಲಗೇಡಿಗಳನ್ನೂ, ಕುಲವನ್ನೂ\nನರಕಕ್ಕೆ ತಳ್ಳುತ್ತದೆ. ಇಂಥವರ ಪೂರ್ವಜರು ಪಿಂಡ-ತರ್ಪಣಗಳಿಲ್ಲದೇ ನರಳುತ್ತಾರೆ.\n\nವಿಕ್ಷಿಪ್ತ ಮನಸ್ಸಿನ ಮಕ್ಕಳು ಹುಟ್ಟುವುದರಿಂದ, ಇಡೀ ಸಮಾಜ ನರಕಕ್ಕೆ ಹೋಗಬೇಕಾಗುತ್ತದೆ. ಹಾಗೂ ಅದಕ್ಕೆ\nಕಾರಣರಾದ ನಾವೂ ಕೂಡಾ ನರಕಕ್ಕೆ ಹೋಗಬೇಕಾಗುತ್ತದೆ. ಸಮಾಜ ಈ ರೀತಿ ಸಂಕೀರ್ಣವಾದಾಗ, ಎಲ್ಲಾ\nನಂಬಿಕಯನ್ನು ಕಳೆದುಕೊಂಡಾಗ, ಪಿತೃಗಳು ಪಿಂಡ ಇಲ್ಲದೆ ನರಕದಲ್ಲಿ ಬೀಳುತ್ತಾರೆ ಎನ್ನುವುದು ಅರ್ಜುನನ\nಯುದ್ಧೋತ್ತರ ಪರಿಣಾಮದ ಭೀಕರತೆಯ ಪರಿಕಲ್ಪನೆ.\nಇಲ್ಲಿ ಪಿಂಡ ಅಂದರೆ ಏನು? ಅದರ ಮಹತ್ವ ಏನು? ಅದು ಯಾರಿಗೆ ಹೋಗಿ ಹೇಗೆ ಸೇರುತ್ತದೆ ಎನ್ನುವುದನ್ನು\nನಾವು ಅರ್ಥ ಮಾಡಿಕೊಳ್ಳೋಣ. ನಾವು ಹಾಕುವ ಸ್ಥೂಲವಾದ ಪಿಂಡ ಸತ್ತ ಜೀವಕ್ಕೆ ನೇರವಾಗಿ ಹೋಗಿ\nಸೇರುವುದಿಲ್ಲ. ಸತ್ತ ನಂತರ ಸೂಕ್ಷ್ಮ ಜೀವದಲ್ಲಿ ಇರುವ ಜೀವಕ್ಕೆ ಸ್ಥೂಲವಾದ ಪಿಂಡ ಬೇಕಿಲ್ಲ. ಜೀವ ತನ್ನ\nಕರ್ಮಾನುಸಾರ ತಾನು ಹೋಗಬೇಕಾದಲ್ಲಿಗೆ ಹೋಗುತ್ತದೆ. ನಾವು ಪಿಂಡ ಹಾಕುವುದು ಪಿತೃದೇವತೆಗಳಿಗೆ.\nಇದೊಂದು ದೇವತಾಗಣ. ಅದರಲ್ಲಿ ಒಟ್ಟು ನೂರು ದೇವತೆಗಳು. ಅವರಲ್ಲಿ ಮೂರು ಪ್ರಧಾನ'`ಪಿತೃಗಳು .\nಜೀವಿತ ಕಾಲದಲ್ಲಿ ತತ್ತ್ವಾಭಿಮಾನಿ ದೇವತೆಗಳನ್ನು ಹೇಗೆ ಪೂಜಿಸುತ್ತೇವೋ ಹಾಗೇ ಸತ್ತ ನಂತರ, ಈ\nಸ್ಥೂಲಶರೀರದಿಂದ ಈಚೆ ಬಂದ ಮೇಲೆ, ಜೀವವನ್ನು ರಕ್ಷಿಸುವ ದೇವತಾಗಣ-ಪಿತೃಗಣ. ಈ ಪಿತೃಗಳನ್ನು\nನಿಯಂತ್ರಿಸುವವರು ವಸು-ರುದ್ರ-ಆದಿತ್ಯರು. ಈ ಪಿತೃ ದೇವತೆಗಳನ್ನು ನಮ್ಮ ಪೂರ್ವಜರು ತೀರಿಕೊಂಡ\nವಾರ್ಷಿಕ ದಿನದಂದು ಆರಾಧಿಸುವುದು ಸಂಪ್ರದಾಯ. ಇಲ್ಲಿ ಪಿತೃಗಳಿಗೆ ಪಿಂಡ ಪ್ರಧಾನ ಮಾಡುವ ಕಾರಣ\nಏನೆಂದರೆ, ಒಂದು ವೇಳೆ ಕಾರಣ ವಿಶೇಷದಿಂದ ನಮ್ಮ ಹಿರಿಯರಿಗೆ ಅವರ ದಾರಿಯಲ್ಲಿ ಬಾಧಕವಾಗಿದ್ದರೆ,\nಅದನ್ನು ಪರಿಹರಿಸಿ ಎನ್ನುವ ಪ್ರಾರ್ಥನೆಯೇ ಪಿಂಡ ಪ್ರಧಾನ. “ಪ್ರಾರಾಬ್ಧ ಕರ್ಮದಿಂದ ಅವರನ್ನು ಕಾಪಾಡಿ”\nಎನ್ನುವ ಪಿತೃ-ದೇವತೆಗಳ ಪೂಜೆ. ಇನ್ನು ಕಾಗೆ ಮುಟ್ಟುವುದು ಎಂದರೆ ಪಿತೃ ದೇವತೆಗಳು ನಮ್ಮ ಪೂಜೆಯನ್ನು\nಸ್ವೀಕರಿಸಿದ ಶಕುನ ಸಂಕೇತ.",
  "1.43": "ದೋಷೈಃ ಏತೈಃ ಕುಲಘ್ನಾನಾಮ್‌ ವರ್ಣಸಂಕರಕಾರಕೈಃ |\nಉತ್ಸಾದ್ಯಂತೇ ಜಾತಿಧರ್ಮಾಃ ಕುಲಧರ್ಮಾಃ ಚ ಶಾಶ್ವತಾಃ -ಸಮಾಜದ ಬಣ್ಣಗೇಡಿಗೆ ಕಾರಣರಾದ\nಕುಲಗೇಡಿಗಳ ಇಂತಹ ತಪ್ಪುಗಳಿಂದ ಸಹಜ ಧರ್ಮಗಳು ಮತ್ತು ಅಳಿವಿರದ ಕುಲಧರ್ಮಗಳು ನೆಲೆಗೆಡುತ್ತವೆ.\n\nಯುದ್ಧದಿಂದ ಸಮಾಜದ ಮೇಲೆ ಆಗುವ ನೇರ ಪರಿಣಾಮ ಎಂದರೆ- ನಾಯಕರಿಲ್ಲದ, ಯುವಕರಿಲ್ಲದ ಸಮಾಜ.\nಗಂಡು-ಹೆಣ್ಣಿನ ಅನುಪಾತ ವ್ಯತ್ಯಾಸ. ಇದು ಸರಿ ಹೊಂದಬೇಕಾದರೆ ಅದೆಷ್ಟು ವರ್ಷಗಳು ಬೇಕು? ನಾವು\nಮಹಾಭಾರತ ಯುದ್ಧವನ್ನು ನೋಡಿದರೆ ಅಲ್ಲಿ ಕನಿಷ್ಠ ಐವತ್ತು ಲಕ್ಷ ಮಂದಿ ಜನ ಸತ್ತಿದ್ದಾರೆ. ಇಂತಹ\n\nಮಹಾಯುದ್ಧದಿಂದ ಇಡೀ ಸಮಾಜ ನಾಶಮಾಡಿದ ಕುಲಕಂಟಕರು ನಾವಾಗುತ್ತೇವೆ ಎನ್ನು ವುದು ಅರ್ಜುನನ\nಕಳಕಳಿ. “ಸಮಾಜದ ವ್ಯವಸ್ಥೆ ನಾಶವಾಗುವುದರಿಂದ ಸ್ವಭಾವ ನಾಶವಾಗುತ್ತದೆ. ಇದರಿಂದ ಆಯಾ ಜೀವದ\nಸ್ವಭಾವದ ಅಭಿವೃದ್ಧಿ ಆಗದೇ, ವ್ಯಕ್ತಿತ್ವ ವಿಕಸನ ನಾಶವಾಗುತ್ತದೆ. ಶಾಶ್ವತ ಮೌಲ್ಯದ ಸಮಾಜಧರ್ಮ\nನಾಶವಾಗುತ್ತದೆ. ಅನಾದಿ ಕಾಲದಿಂದ ಸಮಾಜ ಒಪ್ಪಿಕೊಂಡು ಬಂದ ಸ್ಥಿರಧರ್ಮ ಕೊಚ್ಚಿಕೊಂಡು ಹೋಗುತ್ತದೆ”\nಎಂದು ಅರ್ಜುನ ಕೃಷ್ಣನ ಮುಂದೆ ತನ್ನ ವಾದವನ್ನು ಮಂಡಿಸುತ್ತಾನೆ.",
  "1.44": "ಉತ್ಸನ್ನ ಕುಲಧರ್ಮಾಣಾಮ್‌ ಮನುಷ್ಯಾಣಾಮ್‌ ಜನಾರ್ದನ |\nನರಕೇ ನಿಯತಮ್‌ ವಾಸಃ ಭವತಿ ಇತಿ ಅನುಶುಶ್ರುಮ- ಓ ಜನಾರ್ಧನಾ, ಕುಲ ಧರ್ಮದ ನೆಲೆದಪ್ಪಿದವರಿಗೆ\nನರಕವೇ ಮುಗಿಯದ ನೆಲೆ ಎಂದು ಕೇಳಿ ಬಲ್ಗೆವು.\n\nಇಹದಲ್ಲೂ ನರಕ, ಪರದಲ್ಲೂ ನರಕ, ಹೀಗೆ ಜನ್ಮವೆಲ್ಲಾ ನರಕದಲ್ಲಿ. ಎಂದೆಂದೂ ನರಕದಲ್ಲೇ ಕೊಳೆಯುವ\nಪರಿಸ್ಥಿತಿ ಬರುತ್ತದೆ ಎಂದು ತಿಳಿದವರು ಹೇಳುವುದನ್ನು ಕೇಳಿ ತಿಳಿದಿದ್ದೇನೆ. ಹೀಗೆ ಇಹವೂ ನರಕ, ಪರವೂ\nನರಕವಾಗಲು ನಾವೇ ಕಾರಣವಾಗುತ್ತೇವೆ.",
  "1.45": "ಅಹೋ ಬತ ಮಹತ್ ಪಾಪಮ್ ಕರ್ತುಮ್ ವ್ಯವಸಿತಾಃ ವಯಮ್ ।\nಯತ್ ರಾಜ್ಯಸುಖಲೋಭೇನ ಹಂತುಮ್ ಸ್ವಜನಮ್ ಉದ್ಯತಾಃ -- ಅಯ್ಯೋ! ಎಂತಹ ಹಿರಿಯ ತಪ್ಪನ್ನು ಮಾಡತೊಡಗಿದ್ದೇವು ನಾವು! ದೊರೆತನದ ಸುಖದ ದುರಾಸೆಯಿಂದ ನಮ್ಮ ಮಂದಿಯನ್ನೇ ಕೊಲ್ಲ ಹೊರಟಿದ್ದೇವಲ್ಲ!\n\nಇಲ್ಲಿ ಅರ್ಜುನ ಕುಸಿದು ಬೀಳುವ ಧ್ವನಿಯಲ್ಲಿ ಹೇಳುತ್ತಾನೆ - \"ಅಯ್ಯೋ.. ಎಂತಹ ದೊಡ್ಡ ದುರಂತ, ಎಂತಹ ದೊಡ್ಡ ಪಾಪ ಕಾರ್ಯ ನಮ್ಮ ಮುಂದೆ ನಡೆಯುತ್ತಿತ್ತು? ಎಂತಹ ಪ್ರಮಾದ ಆಗಿ ಹೋಗುತ್ತಿತ್ತು? ನಾವು ದೊಡ್ಡ ತಪ್ಪನ್ನು ಮಾಡಲು ಕೈ ಹಾಕುತ್ತಿದ್ದೇವು. ರಾಜ್ಯ ಸುಖದ ಲೋಭದಿಂದ ನಮ್ಮ ಜನರನ್ನೇ ನಾವು ಕೊಂದು ಇಡೀ ಜನಾಂಗವನ್ನು ಅಧಃಪಾತಕ್ಕೆ ತಳ್ಳುವ ಕೆಲಸ ನಮ್ಮಿಂದಾಗುತ್ತಿತ್ತು\" ಎಂದು.",
  "1.46": "ಯದಿ ಮಾಮ್‌ ಅಪ್ರತೀಕಾರಮ್‌ ಅಶಸ್ತ್ರಮ್‌ ಶಸ್ತ್ರಪಾಣಯಃ |\nಧಾರ್ತರಾಷ್ಟ್ರಾಃ ರಣೇ ಹನ್ಯುಃ ತತ್‌ ಮೇ ಕ್ಷೇಮ ತರಮ್‌ ಭವೇತ್‌ -- ಒಂದೊಮ್ಮೆ ಎದುರು ನಿಂತು ಹೋರಾಡದ,\nಆಯುಧ ಹಿಡಿಯದ ನನ್ನನ್ನು ಧಾರ್ತರಾಷ್ಟ್ರರು ಆಯುಧ ಹಿಡಿದು ಕೊಲ್ಲುವುದಾದರೆ ಅದು ನನ್ನ ಭಾಗ್ಯವಾದೀತು.\n\nನಾನು ಪ್ರತೀಕಾರ ಮಾಡುವುದೇ ಇಲ್ಲ. ಒಂದು ವೇಳೆ ಅವರು ನನ್ನನ್ನು ಹೊಡೆಯಲು ಬಂದರೆ ನಾನು\nಪ್ರತಿಯಾಗಿ ಹೊಡೆಯುವುದೂ ಇಲ್ಲ. ಕತ್ತಿ ಹಿಡಿದು ನನ್ನನ್ನು ಕೊಂದರೆ ಅದು ನನ್ನ ಭಾಗ್ಯವೆಂದು ನಾನು\nಸಾಯುತ್ತೇನೆ. ಏಕೆ ಇಂತಹ ದುರಂತ ನೋಡಿ ಬದುಕಬೇಕು? ಏನಾದರೂ ಸರಿ, ನನಗೆ ಯುದ್ಧ ಬೇಡ. ಎಂದು\nಅರ್ಜುನ ಕೈಚೆಲ್ಲುತ್ತಾನೆ.\n\nಯುದ್ಧ ಪ್ರಾರಂಭದಲ್ಲಿ \"ಸೇನಯೋರುಭಯೋರ್ಮಧ್ಯೇ ರಥಂ ಸ್ಥಾಪಯ ಮೇಚ್ಯುತ”\" ಎಂದು ದರ್ಪದಿಂದ ಹೇಳಿದ\nಅರ್ಜುನ- ಕ್ಷಣ ಮಾತ್ರದಲ್ಲಿ ಕರಗಿ ಹೋದ. ಇದು ಆತನ ಸುಪ್ತಪ್ರಜ್ಞೆಯಲ್ಲಿ ಅವನಿಗೆ ತಿಳಿಯದಂತೆ ಅಡಗಿ\nಕುಳಿತಿದ್ದ ಭಾವನೆ. ಕೃಷ್ಣ ತನ್ನ ಮನಃಶಾಸ್ತ್ರೀಯ ಚಿಕಿತ್ಸೆ ಯಿಂದ ಅದನ್ನು ಸಂಪೂರ್ಣ ಹೊರ\nಬೀಳುವಂತೆ ಮಾಡಿದ. ಇದು ಮಾನಸಿಕ ಸಂಘರ್ಷಕ್ಕೊಳಗಾದವನಿಗೆ ಮೊದಲು ಮಾಡುವ ಚಿಕಿತ್ಸೆ. ಮನುಷ್ಯನ\nಮನೋರೋಗವನ್ನು ಹೇಗೆ ಗುಣಪಡಿಸಬಹುದು ಎಂದು ಜಗತ್ತಿಗೆ ತೋರಿಸಿದ ಮೊದಲ ಮಹಾ ಮನೋವಿಜ್ಞಾನಿ\nಕೃಷ್ಣ. ಒಂದು ವೇಳೆ ಕೃಷ್ಣ ಅರ್ಜುನನ ಆತ್ಮೀಯರ ಮುಂದೆ ರಥವನ್ನು ನಿಲ್ಲಿಸದೇ ಇದ್ದಿದ್ದರೆ, ಈ ಎಲ್ಲಾ\nವಿಚಾರಗಳು ಆತನ ಮನಸ್ಸಿನಿಂದ ಹೊರ ಬರುತ್ತಿರಲಿಲ್ಲ. ಶ್ರೀಕೃಷ್ಣನ ಈ ಮಾನಸಿಕ ಚಿಕಿತ್ಸೆ,\nತತ್ವಶಾಸ್ತ್ರದೊಂದಿಗೆ ಮನಃಶಾಸ್ತ್ರವನ್ನು ಅರಿತು ವಿಶ್ಲೇಷಿಸಿದಾಗ ಮಾತ್ರ ನಮಗೆ ಅರ್ಥವಾಗುತ್ತದೆ.",
  "1.47": "ಸಂಜಯ ಉವಾಚ -ಸಂಜಯ ಹೇಳಿದನು:\n\nಏವಮ್‌ ಉಕ್ತ್ವಾ ಅರ್ಜುನಃ ಸಂಖ್ಯೇ ರಥ ಉಪಸ್ಥೇ ಉಪಾವಿಶತ್‌ |\n\nವಿಸೃಜ್ಯ ಸಶರಮ್‌ ಚಾಪಮ್‌ ಶೋಕ ಸಂವಿಗ್ನ ಮಾನಸಃ -- ಕಾಳಗದ ಕಣದಲ್ಲಿ ಅರ್ಜುನ ಬಿಲ್ಲು ಬಾಣಗಳನ್ನು\nಬಿಸುಟು, ಅಳಲಿನಿಂದ ತಳಮಳಿಸುತ್ತಾ ತೇರ ಮಡಿಲಲ್ಲಿ ಕುಳಿತುಬಿಟ್ಟ.\n\nರಥದಲ್ಲೇ ನಿಂತು. ಇಷ್ಟು ಮಾತನಾಡಿದ ಅರ್ಜುನ, ರಥದ ಮಧ್ಯದಲ್ಲಿ ಕುಸಿದು ಕುಳಿತುಬಿಟ್ಟ. ತನ್ನೆಲ್ಲಾ\nಶಸ್ತ್ರಾಸ್ತ್ರಗಳನ್ನು ಕೆಳಗೆ ಬಿಟ್ಟು ಕೈಚೆಲ್ಲಿ ಕುಳಿತು ಬಿಟ್ಟ.\n\nಈ ಅಧ್ಯಾಯದಲ್ಲಿ ಅರ್ಜುನ ತನ್ನೆಲ್ಲಾ ಭಾವನೆಗಳನ್ನು ಕೃಷ್ಣನ ಮುಂದೆ ಬಿಚ್ಚಿಟ್ಟಿದ್ದಾನೆ. ಅರ್ಜುನ ಮಾತನಾಡಿದ\nಪ್ರತಿಯೊಂದು ವಿಷಯ ನಮಗೆ ತಿಳಿದ ವಿಷಯ. ಆದರೆ ಮುಂದೆ ಕೃಷ್ಣ ಹೇಳುವುದು ನಮಗೆ ತಿಳಿಯದ್ದು.\nಕತ್ತಲೆಯಿಂದ ಬೆಳಕಿನೆಡೆಗೆ ಕೊಂಡೊಯ್ಯುವ ಭಗವಂತನ ಉತ್ತರವನ್ನು ಮುಂದಿನ ಅಧ್ಯಾಯಗಳಲ್ಲಿ\nನೋಡೋಣ.\n\nಮುಂದಿನ ಅಧ್ಯಾಯಕ್ಕೆ ಹೋಗುವ ಮುನ್ನ ಒಂದು ಪುಟ್ಟ ವಿಶ್ಲೇಷಣೆ. ನಮ್ಮಲ್ಲಿ ಹೆಚ್ಚಿನವರಿಗೆ ಒಂದು\nಅನುಮಾನವಿದೆ. ಯುದ್ಧ ಭೂಮಿಯಲ್ಲಿ ಶ್ರೀಕೃಷ್ಣ ಮತ್ತು ಅರ್ಜುನ ಹೇಗೆ ಈ ಏಳುನೂರು ಶ್ಲೋಕಗಳ ಸಂಭಾಷಣೆ\nಮಾಡಿದರು? ಅವರಿಗೆ ಅಷ್ಟು ಸಮಯ ಇತ್ತೇ? ಎಂದು. ಈ ಪ್ರಶ್ನೆಗೆ ಉತ್ತರ ದೊರೆಯಬೇಕಾದರೆ ಮೊದಲು\nನಾವು ಮಹಾಭಾರತ ಕಾಲದ ಯುದ್ಧ ಪದ್ಧತಿಯನ್ನು ತಿಳಿದಿರಬೇಕು. ಆಗಿನ ಕಾಲದ ಯುದ್ಧ ನಿಯಮದ ಪ್ರಕಾರ\nಯುದ್ಧದಲ್ಲಿ ಎದುರಾಳಿ ಸಿದ್ಧವಿಲ್ಲದಿದ್ದರೆ ಅವನ ಮೇಲೆ ಆಕ್ರಮಣ ಮಾಡುವಂತಿರಲಿಲ್ಲ. ಒಬ್ಬ ಸಜ್ಜಾಗಿ ನಿಲ್ಲದೆ\nಯುದ್ಧ ಪ್ರಾರಂಭವಾಗುತ್ತಿರಲಿಲ್ಲ. ಇನ್ನು ಎಷ್ಟು ಹೊತ್ತು ಅವರ ಸಂಭಾಷಣೆ ನಡೆಯಿತು ಎನ್ನುವ ಪ್ರಶ್ನೆ. ಅರ್ಜುನ\nಆ ಕಾಲದ ಮಹಾಮೇಧಾವಿಗಳಲ್ಲಿ ಒಬ್ಬ. ಇಲ್ಲಿ ಸಂಭಾಷಣೆ ನೆಡೆಯುತ್ತಿರುವುದು ಇಬ್ಬರು ಮೇಧಾವಿಗಳ ನಡುವೆ.\nಆ ಮಟ್ಟದ ಜ್ಞಾನವನ್ನು ಇಂದು ನಾವು ಊಹಿಸುವುದೂ ಕಷ್ಟ. ಅವರ ಸಂಪೂರ್ಣ ಸಂಭಾಷಣೆ ನಡೆದಿದ್ದು ಇಂದಿನ\nಈ ಏಳುನೂರು ಶ್ಲೋಕ ರೂಪದಲ್ಲಿ ಅಲ್ಲ. ವೇದವ್ಯಾಸರು ಅವರ ಸಂಭಾಷಣೆಯನ್ನು ನಮಗೆ ಅರ್ಥವಾಗುವಂತೆ\nಏಳುನೂರು ಶ್ಲೋಕ ರೂಪದಲ್ಲಿ ನಮ್ಮ ಮುಂದಿಟ್ಟಿದ್ದಾರೆ ಅಷ್ಟೆ. ಇಂದು ನಮಗೆ ಈ ಶ್ಲೋಕ ಕೂಡಾ\nಅರ್ಥವಾಗುವುದಿಲ್ಲ. ಅದಕ್ಕಾಗಿ ನಾವು ಗೀತೆಯ ಭಾಷ್ಯವನ್ನು ಸಾವಿರಾರು ಪುಟಗಳಲ್ಲಿ ಕಾಣುತ್ತೇವೆ. ಆದರೆ\nಮಹಾ ಮೇಧಾವಿಗಳು ಇದನ್ನು ಅತೀ ಸಂಕ್ಷಿಪ್ತವಾಗಿ ಅತೀ ಕಡಿಮೆ ಸಮಯದಲ್ಲಿ ಹೇಳಬಲ್ಲರು ಹಾಗೂ ಅರ್ಥ\nಮಾಡಿಕೊಳ್ಳಬಲ್ಲರು. ಕೃಷ್ಣ ಮತ್ತು ಅರ್ಜುನರ ನಡುವೆ ನಡೆದ ಸಂಭಾಷಣೆ ಕೂಡಾ ಇಂತಹ ವಿಷಯಭರಿತ\nಸಂಕ್ಷಿಪ್ತ ಸಂಭಾಷಣೆ.\n\nಇನ್ನೊಂದು ಮುಖ್ಯ ವಿಷಯ ಎಂದರೆ ಗೀತೆಯನ್ನು ಕೃಷ್ಣ ಅರ್ಜುನನಿಗೇ ಏಕೆ ಹೇಳಿದ? ಆತನ ಅಣ್ಣ ಭೀಮನಿಗೆ\nಅಥವಾ ಇತರರಿಗೆ ಏಕೆ ಹೇಳಲಿಲ್ಲ? ಎನ್ನುವ ಪ್ರಶ್ನೆ. ಈ ಪ್ರಶ್ನೆಗೆ ಉತ್ತರ ಅತಿ ಸುಲಭ. ರೋಗ ಬಂದವನಿಗೆ\nಮದ್ದೇ ಹೊರತು ಇತರರಿಗಲ್ಲ. ಅಲ್ಲಿ ಮಾನಸಿಕವಾಗಿ ಆಂತರಿಕ ತುಮುಲದಲ್ಲಿದ್ದವನು ಅರ್ಜುನ ಮಾತ್ರ.\nಅದಕ್ಕಾಗಿ ಶ್ರೀಕೃಷ್ಣ ಅರ್ಜುನನಿಗೆ(ಆತನ ಮುಖೇನ ನಮಗೆ) ಗೀತೋಪದೇಶ ಮಾಡಿದ.",
  "1.73": "ಯೇಷಾಮ್‌ ಅರ್ಥೇ ಕಾಂಕ್ಷಿತಂ ನಃ ರಾಜ್ಯಂ ಭೋಗಾಃ ಸುಖಾನಿ ಚ।\nತೇ ಇಮೇ ಅವಸ್ಥಿತಾಃ ಯುದ್ಧೇ ಪ್ರಾಣಾನ್‌ ತ್ಯಕ್ತ್ವಾ ಧನಾನಿ ಚ - ಯಾರಿಗಾಗಿ ಅರಸೊತ್ತಿಗೆ? ಸುಖ-\n\nಭೋಗಕ್ಕಾಗಿ ಇವರು ಹರಣದ ಮತ್ತು ಹಣದ ಹಂಗು ತೊರೆದು ಕಾಳಗದ ಕಣದಲ್ಲಿ ನಿಂತಿದ್ದಾರೆ.\n\nಒಂದು ವೇಳೆ ಈ ರಾಜಭೋಗ ಬೇಕಿದ್ದರೆ ಅದು ಯಾರಿಗೋಸ್ಕರ? ನಮ್ಮೆಲ್ಲಾ ಗುರು ಹಿರಿಯರ ಮಧ್ಯೆ\nಸಂತೋಷದಿಂದ ನಾವಿರಬೇಕು. ಅವರನ್ನೆಲ್ಲಾ ಕೊಂದು ನಾವೇನು ಸಂತೋಷಪಡುವುದು? ಯಾರಿಗೋಸ್ಕರ\n\nಈ ಜೀವನದ ಸುಖವನ್ನು, ಸಾಮ್ರಾಜ್ಯವನ್ನು ಬಯಸುತ್ತಿದ್ದೇವೋ, ಅವರೆಲ್ಲರೂ ಪ್ರಾಣದ ಹಂಗನ್ನು ತೊರೆದು,\nಸರ್ವಸ್ವವನ್ನೂ ಕಳೆದುಕೊಳ್ಳಲು ಸಿದ್ಧರಾಗಿ ನಮ್ಮೆದುರು ಯುದ್ಧಕ್ಕೆ ನಿಂತಿದ್ದಾರೆ.\n\nಆಚಾರ್ಯಾಃ ಪಿತರಃ ಪುತ್ರಾಸ್ತಥೈವ ಚ ಪಿತಾಮಹಾಃ ।\n\nಮಾತುಲಾಃ ಶ್ವಶುರಾಃ ಪೌತ್ರಾಃ ಸ್ಯಾಲಾಃ ಸಂಬಂಧಿನಸ್ತಥಾ",
  "2.1": "ಸಂಜಯ ಉವಾಚ-ಸಂಜಯ ಹೇಳಿದನು:\n\nತಮ್‌ ತಥಾ ಕೃಪಯಾ ಆವಿಷ್ಟಮ್‌ ಅಶ್ರು ಪೂರ್ಣ ಆಕುಲ ಈಕ್ಷಣಮ್‌ |\n\nವಿಷೀದಂತಮ್‌ ಇದಮ್‌ ವಾಕ್ಯಮ್‌ ಉವಾಚ ಮಧುಸೂದನಃ -ಹಾಗೆ ಕಾರುಣ್ಯಕ್ಕೊಳಗಾಗಿ ಕಂಬನಿ ತುಂಬಿ ಕಣ್ಣು\nಮಸುಕಾಗಿ ಉಮ್ಮಳಿಸುತ್ತಿರುವ ಅವನನ್ನು ಕಂಡು ಕೃಷ್ಣ ಈ ಮಾತು ನುಡಿದ.",
  "2.2": "ಭಗವಾನ್‌ ಉವಾಚ-ಭಗವಂತ ಹೇಳಿದನು:\n\nಕುತಃ ತ್ವಾ ಕಶ್ಮಲಮ್‌ ಇದಮ್‌ ವಿಷಮೇ ಸಮುಪಸ್ಥಿತಮ್‌ |\n\nಅನಾರ್ಯ ಜುಷ್ಪಮ್‌ ಅಸ್ವರ್ಗ್ಯಮ್‌ ಅಕೀರ್ತಿ ಕರಮ್‌ ಅರ್ಜುನ - ಅರ್ಜುನಾ, ಇಂತಹ ಸಂಕಟದಲ್ಲಿ ಬಲ್ಲವರು\nಮೆಚ್ಚದ, ಅಲ್ಲಿ ಸ್ವರ್ಗಕ್ಕೆ ಸಲ್ಲದ, ಇಲ್ಲಿ ಹೆಸರುಗೆಡಿಸುವ ಈ ಕೊಳೆ ನಿನ್ನನ್ನೇಕೆ ಕವಿಯಿತು?\n\n\"ಎಲ್ಲಿಂದ ಬಂತು ನಿನಗೆ ಈ ಬುದ್ಧಿ? ಈ ಭೌತಿಕ ಕೊಳೆ ನಿನಗೆ ಹೇಗೆ ಅಂಟಿತು? ಇಂತಹ ತುರ್ತುಪರಿಸ್ಥಿತಿಯಲ್ಲಿ,\nತಕ್ಷಣ ಕಾರ್ಯಪ್ರವೃತ್ತರಾಗಬೇಕಾದ ಈ ಕ್ಷಣದಲ್ಲಿ-ಇದೇನು ಹೊಲಸು ಯೋಚನೆ? ಆರ್ಯರಾದವರು ಯಾರೂ\nಈ ರೀತಿ ಎಂದೂ ಯೋಚಿಸುವುದಿಲ್ಲ. ಇಂತಹ ವಿಚಾರಧಾರೆಯಿಂದ- ಪರದಲ್ಲಿ ಸ್ವರ್ಗವಿಲ್ಲ ಹಾಗೂ ಇಹದಲ್ಲಿ\n\nಕೀರ್ತಿ ಇಲ್ಲ. ತಿಳಿದವರು, ಜ್ಞಾನಿಗಳು, ಹಿರಿಯರು ಎಂದೂ ಈ ರೀತಿ ಯೋಚನೆ ಮಾಡುವುದಿಲ್ಲ”-ಎಂದು\nನಿಷ್ಠುರವಾಗಿ ಅರ್ಜುನನ ಸಂಪೂರ್ಣ ವಾದವನ್ನು ಒಂದೇ ಮಾತಿನಲ್ಲಿ ಹೊಡೆದು ಹಾಕಿದ ಕೃಷ್ಣ. ಇಲ್ಲಿ\nಬಳಕೆಯಾದ \"ಆರ್ಯ\" ಎನ್ನುವ ಪದ ಜನಾಂಗ ವಾಚಕ ಪದ ಅಲ್ಲ. ಆರ್ಯ ಎಂದರೆ ತಿಳುವಳಿಕೆ ಇರುವವರು,\nವಯೋವೃದ್ಧ ಜ್ಞಾನಿಗಳು, ಗೌರವಾನ್ವಿತರು ಎಂದರ್ಥ. ಕನ್ನಡದಲ್ಲಿ 'ಅಯ್ಯಾ' ಎನ್ನುವ ಪದಕ್ಕೆ ಇದೇ ಅರ್ಥವಿದೆ.",
  "2.3": "ಕ್ಲೈಬ್ಯಮ್ ಮಾ ಸ್ಮ ಗಮಃ ಪಾರ್ಥ ನ ಏತತ್ ತ್ವಯಿ ಉಪಪದ್ಯತೇ |\nಕ್ಷುದ್ರಮ್ ಹೃದಯ ದೌರ್ಬಲ್ಯಮ್ ತ್ಯಕ್ತ್ವಾ ಉತ್ತಿಷ್ಠ ಪರಂತಪ -- ಪಾರ್ಥಾ, ಹೇಡಿಯಾಗಬೇಡ, ನಿನ್ನಲ್ಲಿ ಇದು ತರವಲ್ಲ. ಅರಿಗಳ ಎದೆಗೆಡಿಸುವ ವೀರನೇ, ಕೀಳರಿಮೆಯ ಎದೆಗೇಡಿತನವನ್ನು ತೊರೆದು ಎದ್ದು ನಿಲ್ಲು.\n\n\"ನಪುಂಸಕನಂತೆ ಮಾತನಾಡಬೇಡ. ಅರ್ಜುನನಲ್ಲಿ ಇಂತಹ ಹೇಡಿತನವನ್ನು ನಾನು ನಿರೀಕ್ಷಿಸಿರಲಿಲ್ಲ. ಇಂತಹ ಕ್ಷುದ್ರ ಮಾನಸಿಕ ದೌರ್ಬಲ್ಯವನ್ನು ತೊಡೆದುಹಾಕಿ, ವೀರನಾಗಿ ಅನ್ಯಾಯದ ವಿರುದ್ಧ ಹೋರಾಡು\" ಎಂದು ಹೇಳಿ ಕೃಷ್ಣ, ಅರ್ಜುನನಿಗೆ ದಿಗ್ಭ್ರಾಂತಿಗೊಳಿಸಿ ಚಿಕಿತ್ಸೆ (Shock Treatment) ನೀಡಿದ್ದಾನೆ.",
  "2.4": "ಅರ್ಜುನಃ ಉವಾಚ-ಅರ್ಜುನ ಹೇಳಿದನು:\n\nಕಥಮ್‌ ಭೀಷ್ಮಮ್‌ ಅಹಮ್‌ ಸಂಖ್ಯೇ ದ್ರೋಣಮ್‌ ಚ ಮಧುಸೂದನ |\n\nಇಷುಭಿಃ ಪ್ರತಿಯೋತ್ಸ್ಯಾಮಿ ಪೂಜಾರ್ಹಾ ಅರಿಸೂದನ- ಅರಿಗಳನ್ನು ತರಿದ ಓ ಮಧುಸೂದನಾ, ಭೀಷ್ಮನನ್ನು,\nದ್ರೋಣನನ್ನು : ಪೂಜಿಸಬೇಕಾದ ಮಂದಿಯನ್ನು ನಾನೆಂತು ರಣದಲ್ಲಿ ಬಾಣಗಳಿಂದ ಹೊಡೆದು ಹೋರಾಡಲೀ?\n\nಕೃಷ್ಣನ ತೀಕ್ಷ್ಣ ಉತ್ತರ ಹಾಗೂ ಆತನ ನಗುಮೊಗವನ್ನು ಗಮನಿಸಿದ ಅರ್ಜುನನ ಮಾತಿನ ದಾಟಿ ಈಗ\nಬದಲಾಗುತ್ತದೆ. ಆತ ಭಾವಾವೇಶ ಬಿಟ್ಟು ಈಗ ಭಾವುಕತೆಯಿಂದ ಶರಣಾಗತಿಯತ್ತ ಹೊರಳುತ್ತಿದ್ದಾನೆ.\n\nಅರ್ಜುನ ಹೇಳುತ್ತಾನೆ: \"ನನ್ನ ಕಣ್ಣಮುಂದೆ ನಿಂತ ಭೀಷ್ಮಾಚಾರ್ಯರು, ದ್ರೋಣಾಚಾರ್ಯರನ್ನು ಹೇಗೆ\nಎದುರಿಸಲೀ? ಒಬ್ಬರು ನಮ್ಮ ವಂಶದ ಮೂಲಪುರುಷನಾದ ರಾಜರ್ಷಿ; ಇನ್ನೊಬ್ಬರು ಎಲ್ಲಾ ಕ್ಷತ್ರಿಯರಿಗೂ ವಿದ್ಯೆ\nಕೊಟ್ಟ ಮಹರ್ಷಿ. ಇಂತಹ ಪೂಜಾರ್ಹರಾದ ಮಹನೀಯರತ್ತ ಹೇಗೆ ಬಾಣ ಹೂಡಲೀ ? ಸೃಷ್ಟಿಯ ಆದಿಯಲ್ಲಿ\nಮಧು-ಕೈತಪರನ್ನು ಸಂಹಾರ ಮಾಡಿದ ಓ ಮಧುಸೂದನನೇ; ದುಷ್ಟ ಸಂಹಾರಕ್ಕೆಂದು ಅವತರಿಸಿದ\nಅರಿಸೂದನನೇ, ಜ್ಞಾನಿಗಳ, ಆಚಾರ್ಯರ ಹತ್ಯೆ ನಿನ್ನ ಮೂಲ ಉದ್ದೇಶ ಅಲ್ಲ\" . ಎಂದು ಭಿನ್ನ ದಾಟಿಯಲ್ಲಿ\nಅರ್ಜುನ ತನ್ನ ಮಾತನ್ನು ಮುಂದುವರಿಸುತ್ತಾನೆ.\n",
  "2.5": "ಗುರೂನ್‌ ಅಹತ್ವಾ ಹಿ ಮಹಾನುಭಾವಾನ್‌ ಶ್ರೇಯಃ ಭೋಕ್ತುಮ್‌ ಭೈಕ್ಷ್ಯಮ್‌ ಅಪಿ ಇಹ ಲೋಕೇ |\n\nಹತ್ವಾ ಅರ್ಥ ಕಾಮಾನ್‌ ತು. ಗುರೂನ್‌ ಇಹ ಏವ ಭುಂಜೀಯ ಭೋಗಾನ್‌ ರುಧಿರ ಪ್ರದಿಗ್ಧಾನ್‌-- ಈ\nಮಹಾನುಭಾವಿಗಳನ್ನು ಕೊಲ್ಲುವ ಬದಲು ಇಲ್ಲೇ, ಈ ನೆಲದಲ್ಲಿ ಭಿಕ್ಷೆ ಬೇಡುವುದು ಮೇಲು. ಸಿರಿಯ ಬೆನ್ನು ಹತ್ತಿದ\nಇವರನ್ನು ಕೊಂದು ಇಲ್ಲೇ ಅವರ ನೆತ್ತರಿನಿಂದ ನೆನೆದ ಐಸಿರಿಯನ್ನುಣ್ಣಬೇಕು!\n\nಗುರು ಹಿರಿಯರನ್ನು ಕೊಂದು, ಸಿರಿವಂತಿಕೆಯ ಭೋಗವನ್ನು ಅನುಭವಿಸುವುದಕ್ಕಿಂತ, ಭಿಕ್ಷೆ ಬೇಡಿ ಬದುಕುವುದು\nಹಿರಿತನವಲ್ಲವೇ? ಯಾವ ಸಿಂಹಾಸನ ಅಂತರಂಗದ ಸತ್ಯವನ್ನು ಸಾಕ್ಷಾತ್ಕಾರ ಮಾಡಿಕೊಂಡ ಭೀಷ್ಮ-\nದ್ರೋಣರಂತಹ ಮಹಾನುಭಾವರನ್ನು ಕೊಡಲಾರದೋ, ಅಂತಹ ಸಿಂಹಾಸನ ನಮಗೇಕೆ ಬೇಕು?\n\nದುರ್ಯೋಧನನ ಸಂಬಳದ ದಾಸರಾಗಿ, ಅರಮನೆಯ ಋಣಕ್ಕಾಗಿ ಹೋರಾಟಕ್ಕೆ ನಿಂತ ಇವರನ್ನು ಕೊಂದು\nಸಿಂಹಾಸನವೇರಿದರೆ, ಗುರುಗಳ ನೆತ್ತರಿನಿಂದ ತೊಯ್ದ ಭೋಗವನ್ನು ಅನುಭವಿಸಿದಂತೆ.",
  "2.6": "ನ ಚ ಏತತ್‌ ವಿದ್ಮಃ ಕತರತ್‌ ನಃ ಗರೀಯಃ ಯತ್‌ ವಾ ಜಯೇಮ ಯದಿ ವಾ ನಃ ಜಯೇಯುಃ |\n\nಯಾನ್‌ ಏವ ಹತ್ವಾ ನ ಜಿಜೀವಿಷಾಮಃ ತೇ ಅವಸ್ಥಿತಾಃ ಪ್ರಮುಖೇ ಧಾರ್ತರಾಷ್ಟ್ರಾಃ-\n-ಇದೇ ತಿಳಿಯುತ್ತಿಲ್ಲ.\nಯಾವುದು ನಮಗೆ ಹೆಚ್ಚು ಒಳಿತು-ನಾವು ಗೆಲ್ಲುವುದೇ? ಅಥವಾ ನಮ್ಮನ್ನು ಅವರು ಗೆಲ್ಲುವುದೇ? ಯಾರನ್ನು\nಕೊಂದು ನಾವು ಬದುಕ ಬಯಸುವುದಿಲ್ಲವೋ, ಅವರು(ಕೌರವರು) ನಮ್ಮೆದುರು ನಿಂತಿದ್ದಾರೆ.\n\nಇಲ್ಲಿಯ ತನಕ ತನ್ನ ವಾದವನ್ನೇ ಮಂಡಿಸಿದ ಅರ್ಜುನ ಈಗ ಕೃಷ್ಣನಿಗೆ ಶರಣಾಗಿ ತನಗ್ಯಾವುದು ಒಳಿತು ಎಂದು\nಪ್ರಶ್ನೆ ಮಾಡುತ್ತಾನೆ. “ನಾವು ಯುದ್ಧ ಮಾಡಿ ಗೆಲ್ಲುವುದರಲ್ಲಿ ನಮಗೆ ಶ್ರೇಯಸ್ಸೋ ಅಥವಾ ಗುರುಹಿರಿಯರು\nಗೆಲ್ಲುವುದರಲ್ಲಿ ನಮಗೆ ಶ್ರೇಯಸ್ಸೋ ತಿಳಿಯುತ್ತಿಲ್ಲ. ಯುದ್ಧದಲ್ಲಿ ಗೆಲ್ಲಬೇಕು ಎನ್ನುವ ಆಸೆಯೂ\nಹೊರಟುಹೋಗಿದೆ” ಎಂದು ತನ್ನ ಮನಸ್ಸಿನ ಸಂಧಿಗ್ಛತೆಯನ್ನು ಅರ್ಜುನ ಕೃಷ್ಣನ ಮುಂದೆ ಬಿಚ್ಚಿಡುತ್ತಾನೆ. ತಂದೆ\nಸಮನಾದ ಧೃತರಾಷ್ಟ್ರ, ಅವರ ಮಕ್ಕಳು ನಮ್ಮ ಮುಂದೆ ಯುದ್ಧಕ್ಕೆ ನಿಂತಿದ್ದಾರೆ. ಮಕ್ಕಳೆಂದರೆ ಪ್ರಾಣ ಬಿಡುವ\nನಮ್ಮ ದೊಡ್ಡಪ್ಪನ ವಿರುದ್ಧ ಹೋರಾಡಲು ಇಷ್ಟವಿಲ್ಲ ಎನ್ನುತ್ತಾನೆ ಅರ್ಜುನ.\n",
  "2.7": "ಕಾರ್ಪಣ್ಯ ದೋಷ ಉಪಹತ ಸ್ವಭಾವಃ ಪೃಚ್ಛಾಮಿ ತ್ವಾಮ್‌ ಧರ್ಮ ಸಮ್ಮೂಢ ಚೇತಾಃ।\n\nಯತ್‌ ಶ್ರೇಯಃ ಸ್ಯಾತ್‌ ನಿಶ್ಚಿತಮ್‌ ಬ್ರೂಹಿ ತತ್‌ ಮೇ ಶಿಷ್ಯಃ ತೇ ಅಹಮ್‌ ಶಾಧಿ ಮಾಮ್‌ ತ್ವಾಮ್‌ ಪ್ರಪನ್ನಮ್‌-\n-ದೌರ್ಬಲ್ಯದ ದೋಷದಿಂದ ನನ್ನ ಸಹಜ ಬೀರಕ್ಕೆ ಮಂಕು ಕವಿದಿದೆ. ಧರ್ಮದ ಬಗೆಗೆ ಬಗೆಗಾಣದವನಾಗಿ\nನಿನ್ನನ್ನು ಕೇಳುತ್ತಿದ್ದೇನೆ; ಹೇಳು ನನಗಿದನ್ನು: ಯಾವುದು ನಿಖರವಾದ ಒಳಿತಿನ ದಾರಿ? ನಾನು ನಿನ್ನ ಶಿಷ್ಯ.\nನಿನಗೆ ಶರಣು ಬಂದ ನನಗೆ ದಾರಿ ತೋರು.\n\nನನಗೆ ಕಾರ್ಪಣ್ಯ ದೋಷ ಬಂದಿದೆ. ಯಾವುದು ಸರಿ ಯಾವುದು ತಪ್ಪು ಎಂದು ತೀರ್ಮಾನ ಮಾಡಲಾರದ\nದಯನೀಯ ಸಸ್ಥಿತಿಯಲ್ಲಿದ್ದೇನೆ. ಧರ್ಮದ ಬಗ್ಗೆ ನನ್ನ ಚಿಂತನಶಕ್ತಿ ಗೊಂದಲದ ಗೂಡಾಗಿದೆ. ಯುದ್ಧ ಬೇಕೋ\nಬೇಡವೋ ಎನ್ನುವ ಗೊಂದಲ ನನ್ನನ್ನು ಕಾಡುತ್ತಿದೆ. ಯಾವುದು ನನಗೆ ಹಿತ ಎಂದು ತಿಳಿಯದಾಗಿದೆ. ನಾನು\nನಿನ್ನ ಶಿಷ್ಯನಾಗಿ ನಿನ್ನಲ್ಲಿ ಶರಣಾಗಿದ್ದೇನೆ. ನನಗೆ ಮಾರ್ಗದರ್ಶನ ಮಾಡು ಎಂದು ಅರ್ಜುನ ಕೃಷ್ಣನಲ್ಲಿ\n\nಕೇಳಿಕೊಳ್ಳುತ್ತಾನೆ. ಇಲ್ಲಿಯ ತನಕ ಭಗವಂತನ ಮುಂದೆ ಪಂಡಿತನಂತೆ ಮಾತನಾಡಿದ ಅರ್ಜುನ, ಈಗ\nಭಗವಂತನಲ್ಲಿ ಶರಣಾಗತಿಯನ್ನು ಬೇಡುತ್ತಿರುವುದು ಇಲ್ಲಿ ಸ್ಪಷ್ಟವಾಗಿ ಕಾಣುತ್ತದೆ.\n",
  "2.8": "ನ ಹಿ ಪ್ರಪಶ್ಯಾಮಿ ಮಮ ಅಪನುದ್ಯಾತ್‌ ಯತ್‌ ಶೋಕಮ್‌ ಉಚ್ಛೋಷಣಮ್‌ ಇಂದ್ರಿಯಾಣಾಮ್‌ |\nಅವಾಪ್ಯ ಭೂಮೌ ಅಸಪತ್ನಮ್‌ ಋದ್ಧಮ್‌ ರಾಜ್ಯಮ್‌ ಸುರಾಣಾಮ್‌ ಅಪಿ ಚ ಆಧಿಪತ್ಯಮ್‌-\n-ಸತ್ಯ ಸಾರವನ್ನೆಲ್ಲಾ ಹೀರಿ ಬತ್ತಿಸಿಬಿಡಬಲ್ಲ ನನ್ನ ಈ ದುಗುಡವನ್ನು ದೂರೀಕರಿಸಬಲ್ಲ ದಾರಿಯನ್ನೇ ಕಾಣದವನಾಗಿದ್ದೇನೆ-ಹಗೆಗಳೇ\nಇಲ್ಲದ, ಹುಲುಸಾದ ಇಡಿಯ ನೆಲದ ಒಡೆತನ ಪಡೆದರೂ, ಸಗ್ಗಿಗರ ಸಾಮ್ರಾಟನಾದರೂ ಕೂಡಾ.\n\n“ನನ್ನ ಇಂದ್ರಿಯಗಳು ಸೊರಗಿ ಹೋಗುತ್ತಿವೆ. ನನ್ನ ದುಃಖವನ್ನು ಹೊಡೆದೋಡಿಸಲು ನನಗೆ ಮಾರ್ಗವೇ\nಕಾಣುತ್ತಿಲ್ಲ. ಭೂಮಿಯಲ್ಲಿ, ಸ್ವರ್ಗದಲ್ಲಿ ಪ್ರಭುತ್ವವನ್ನು ಪಡೆದರೂ ಕೂಡಾ ನಾನು ಈ ದುಃಖವನ್ನು\nಹೋಗಲಾಡಿಸಿಕೊಳ್ಳಲಾರೆ” ಎನ್ನುತ್ತಾನೆ ಅರ್ಜುನ.",
  "2.9": "ಸಂಜಯ ಉವಾಚ -ಸಂಜಯ ಹೇಳಿದನು:\n\nಏವಮ್‌ ಉಕ್ತ್ವಾ ಹೃಷೀಕೇಶಮ್‌ ಗುಡಾಕೇಶಃ ಪರಂತಪಃ |\n\nನ ಯೋತ್ಸ್ಯೇ ಇತಿ ಗೋವಿಂದಮ್‌ ಉಕ್ತ್ವಾ ತೂಷ್ಣೀಮ್‌ ಬಭೂವ ಹ- ಅರಿಗಳನ್ನು ತರಿದ, ನಿದ್ದೆಯನ್ನು ಗೆದ್ದ\nಅರ್ಜುನ-ಇಂದ್ರಿಯಗಳ ಒಡೆಯನಾದ ಗೋವಿಂದನ ಬಳಿ ಹೀಗೆಂದು- ಮತ್ತೆ 'ನಾನು ಕಾದಲಾರೆ' ಎಂದು\nಸುಮ್ಮನಾದನು!\n\nಸಂಜಯ ಯುದ್ಧಭೂಮಿಯಲ್ಲಿ ಅರ್ಜುನನ ಸ್ಥಿತಿಯನ್ನು ಧೃತರಾಷ್ಟ್ರನಿಗೆ ವರ್ಣಿಸುತ್ತಾ, ಈ ರೀತಿ ಹೇಳುತ್ತಾನೆ:\n\"ಇಡೀ ಬ್ರಹ್ಮಾಂಡದಲ್ಲಿ ತುಂಬಿರುವ ನಮ್ಮ ಇಂದ್ರಿಯಗಳ ಸ್ವಾಮಿ ಗೋವಿಂದನಲ್ಲಿ ನಿದ್ದೆಯನ್ನು ಗೆದ್ದ ಅರ್ಜುನ\n'ನಾನು ಯುದ್ಧ ಮಾಡಲಾರೆ' ಎಂದು ಹೇಳಿ ಮೌನಿಯಾದ” ಎಂದು.\n",
  "2.10": "ತಮ್‌ ಉವಾಚ ಹೃಷೀಕೇಶಃ ಪ್ರಹಸನ್‌ ಇವ ಭಾರತ |\nಸೇನಯೋಃ ಉಭಯೋಃ ಮಧ್ಯೇ ವಿಷೀದಂತಮ್‌ ಇದಮ್‌ ವಚಃ -ಓ ಭರತ ವಂಶದ ದೊರೆಯೇ, ಎರಡು\nಪಡೆಗಳನಡುವೆ ತಳಮಳಗೊಂಡಿರುವ ಅವನನ್ನು ಕುರಿತು ಕೃಷ್ಣ ಮೆಲುನಗುತ್ತಾ ಈ ಮಾತು ನುಡಿದ.\n\nಅರ್ಜುನ ಸಂಪೂರ್ಣ ಶರಣಾಗಿ ತನ್ನಮುಂದೆ ಅಂಗಲಾಚಿ ನಿಂತಾಗ, ಶ್ರೀಕೃಷ್ಣ ನಸುನಗುತ್ತಾ ತನ್ನ ಮಾತನ್ನು\nಆರಂಭಿಸುತ್ತಾನೆ. ಇಲ್ಲಿ ಅರ್ಜುನ ಕೃಷ್ಣ ಹೇಳುವುದನ್ನು ಸ್ವೀಕರಿಸುವ ಹಂತವನ್ನು ತಲುಪಿದ್ದಾನೆ. ಆತನಲ್ಲಿ\nಭಾವಾವೇಶ ಹೊರಟುಹೋಗಿ ಶರಾಣಗತಿ ಬಂದಿದೆ. ಭಗವಂತ ನಮಗೆ ಮಾರ್ಗದರ್ಶನ ಮಾಡಬೇಕಾದರೆ\nನಾವು ನಮ್ಮ ಅಹಂಕಾರವನ್ನು ತೊರೆದು, ಆತನಲ್ಲಿ ಸಂಪೂರ್ಣ ಶರಣಾಗಬೇಕು. ಆಗ ಖಂಡಿತ ನಮಗೆ\nಮಾರ್ಗದರ್ಶನ ಸಿಗುತ್ತದೆ. ಇಲ್ಲಿ ಕೃಷ್ಣ ಅರ್ಜುನನಿಗೆ ಮಾಡುವ ಉಪದೇಶ ನಮ್ಮೆಲ್ಲರಿಗೆ ಆತ ಮಾಡಿದ\nಉಪದೇಶ. ಈ ಅಂಶವನ್ನು ಮನಸ್ಸಿನಲ್ಲಿಟ್ಟುಕೊಂಡು ಕೃಷ್ಣನ ಉಪದೇಶವನ್ನು ಆಲಿಸೋಣ ಬನ್ನಿ.\n\nಭಗವಾನುವಾಚ ।\nಅಶೋಚ್ಯಾನನ್ವಶೋಚಸ್ತ್ವಂ ಪ್ರಜ್ಞಾವಾದಾಂಶ್ಚ ಭಾಷಸೇ |\n\nಗತಾಸೂನಗತಾಸೂಂಶ್ಚ ನಾನುಶೋಚಂತಿ ಪಂಡಿತಾಃ",
  "2.11": "ಭಗವಾನ್‌ ಉವಾಚ-ಭಗವಂತ ಹೇಳಿದನು:\n\nಅಶೋಚ್ಯಾನ್‌ ಅನ್ವಶೋಚಃ ತ್ವಮ್‌ ಪ್ರಜ್ಞಾವಾದಾನ್‌ ಚ ಭಾಷಸೇ |\n\nಗತ ಅಸೂನ್‌ ಅಗತ ಅಸೂನ್‌ ಚ ನ ಅನುಶೋಚಂತಿ ಪಂಡಿತಾಃ -ಅಳಬಾರದವರಿಗಾಗಿ ನೀನು ಅಳುತ್ತಿರುವೆ.\nತಿಳಿದವರು ಆಡದಂತಹ ಮಾತುಗಳನ್ನು ತೋಚಿದಂತೆ ಆಡುತ್ತಿರುವೆ. ಅಳಿದವರ ಬಗೆಗಾಗಲೀ, ಅಳಿಯದವರ\nಬಗೆಗಾಗಲೀ, ತಿಳಿದವರು ಅಳುವುದಿಲ್ಲ.\n\nಇದು ಭಗವಂತನ ಉಪದೇಶದ ಮೊದಲ ನುಡಿ. ಇದು ಇಡೀ ಗೀತೆಗೆ ಪಂಚಾಂಗ ರೂಪದಲ್ಲಿದೆ. ಇಲ್ಲಿ ಕೃಷ್ಣ\nಅರ್ಜುನನಿಗೆ ಹೇಳುತ್ತಾನೆ: \"ಯಾರಿಗೋಸ್ಕರ ಅಳಬಾರದೋ ಅಂತವರಿಗೋಸ್ಕರ ಅಳುತ್ತಿರುವೆ. ತುಂಬಾ\nತಿಳಿದ ಮಹಾಜ್ಞಾನಿಯಂತೆ ಮಾತನಾಡುತ್ತಿರುವೆ” ಎಂದು. ಇದು ಅರ್ಜುನನ ದೌರ್ಬಲ್ಯಕ್ಕೆ ಕೃಷ್ಣ ಹಿಡಿದ ಕನ್ನಡಿ.\nಇಲ್ಲಿ 'ನಿನಗೇನೂ ತಿಳಿದಿಲ್ಲ' ಎನ್ನುವ ಭಾವ ಕೂಡಾ ಸ್ಪಷ್ಟವಾಗಿದೆ. ಅರ್ಜುನನಿಗೆ ಕಾಡಿರುವುದು ಕೆಲವರು(ಗುರು-\nಹಿರಿಯರು) ಸಾಯುತ್ತಾರೆ ಇನ್ನು ಕೆಲವರು(ದುಷ್ಟರು) ಬದುಕುತ್ತಾರಲ್ಲಾ ಎನ್ನುವ ಭಯ-ಅದರಿಂದಾಗಿ ದುಃಖ.\nದುಃಖಕ್ಕೆ ಮೂಲ ಭಯ-ಭಯಕ್ಕೆ ಮೂಲ ಅಜ್ಞಾನ.\n\nಇಲ್ಲಿ ನಿಮಗೊಂದು ಪ್ರಶ್ನೆ ಬರಬಹುದು. ಭೀಷ್ಮ ದ್ರೋಣರಂತಹ ಮಹಾತ್ಮರು ಸತ್ತರೆ ಅಳುವುದು ತಪ್ಪೇ? ಈ\nಪ್ರಶ್ನೆ ಗೆ ಉತ್ತರ ಸಿಗಬೇಕಾದರೆ ನಾವು ಹುಟ್ಟು ಸಾವಿನ ಗುಟ್ಟನ್ನು ಅರಿತಿರಬೇಕು. ಹುಟ್ಟು ಸಾವಿನ ಇನ್ನೊಂದು\nಆಯಾಮ ತಿಳಿದಾಗ ನಮಗೆ ಈ ಪ್ರಶ್ನೆಗೆ ಉತ್ತರ ಸಿಗುತ್ತದೆ. ಜೀವ ಅನಾದಿನಿತ್ಯ; ಅದಕ್ಕೆಂದೂ ಸಾವಿಲ್ಲ. ಈ\nಭೌತಿಕ ಶರೀರ ಜೀವಕ್ಕೆ ಒಂದು ಪಂಜರದಂತೆ. ಈ ಪಂಜರದಲ್ಲಿ ಸಿಕ್ಕಿ ಹಾಕಿಕೊಳ್ಳುವುದು ಹುಟ್ಟು. ಪಂಜರದಿಂದ\n\nಹೊರ ಹೋಗುವುದು ಸಾವು. ಈ ಆಯಾಮದಲ್ಲಿ ನೋಡಿದರೆ ಹೊಸ ಅಂಗಿ ತೊಡುವುದು ಹುಟ್ಟು-ಹಳೆ ಅಂಗಿ\nತೊರೆಯುವುದು ಸಾವು. ಈ ಜ್ಞಾನ ನಮಗಿದ್ದರೆ ನಮಗೆ ಸಾವಿನ ಭಯವಿರುವುದಿಲ್ಲ.\n\nಇಲ್ಲಿ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: \"ಜ್ಞಾನಿಗಳು ಆಡುವ ಮಾತನ್ನು ನೀನು ಆಡುತ್ತಿಲ್ಲ” ಎಂದು. ಏಕೆಂದರೆ ಜ್ಞಾನಿಗಳು\nಹುಟ್ಟು-ಸಾವಿನ ಮರ್ಮವನ್ನು ಚೆನ್ನಾಗಿ ಅರಿತಿರುತ್ತಾರೆ. ನೀನು ಆಡುತ್ತಿರುವುದು ತಿಳುವಳಿಕೆಯ ಮಾತಲ್ಲ. ನಿನ್ನ\nತಿಳುವಳಿಕೆಯೇ ವಿಶ್ವದ ಸತ್ಯ ಎನ್ನುವ ಭ್ರಮೆಯಿಂದ ನೀನು ಮಾತನಾಡುತ್ತಿದ್ದೀಯ ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.\n\nಇಲ್ಲಿ ಕೃಷ್ಣ ಅರ್ಜುನ ಹಾಕಿದ ಎಲ್ಲಾ ಲೌಕಿಕ ಪ್ರಶ್ನೆಗಳನ್ನು ಬಿಟ್ಟು ಅವನಿಗೆ ಸತ್ಯದ ಸಾಕ್ಷಾತ್ಕಾರ\nಮಾಡಿಸುತ್ತಿದ್ದಾನೆ. ಅರ್ಜುನ ಕಂಡಿದ್ದು ಕೇವಲ ಐಹಿಕ ಪ್ರಪಂಚವಾದರೆ, ಕೃಷ್ಣ ಆತನಿಗೆ ಅದರಾಚೆಗಿನ ಸತ್ಯದ\nಇನ್ನೊಂದು ಮುಖದ ಪರಿಚಯ ಮಾಡಿಸುತ್ತಿದ್ದಾನೆ.\n\nಸಾವು ಭಯಾನಕವಲ್ಲ, ಹುಟ್ಟಿ ಬಂದವನಿಗೆ ಸಾವು ಅನಿವಾರ್ಯ. ಆತ್ಮಕ್ಕೆ ಎಂದೂ ಸಾವಿಲ್ಲ. ಆತ್ಮ ಅನಾದಿನಿತ್ಯ.\nಆದರೆ ದೇಹ ನಾಶ ಅನಿವಾರ್ಯ. ಮನುಷ್ಯ ತನ್ನ ವಿಕೃತಿಯಿಂದ ಪ್ರಕೃತಿಯೆಡೆಗೆ ಪಯಣಿಸುವ ಕ್ರಿಯೆ ಸಾವು.\nಆದ್ದರಿಂದ ಅಳಿದವರ ಬಗೆಗಾಗಲೀ, ಅಳಿಯದವರ ಬಗೆಗಾಗಲೀ, ತಿಳಿದವರು ಅಳುವುದಿಲ್ಲ ಎನ್ನು ವುದನ್ನು ಇಲ್ಲಿ\nಕೃಷ್ಣ ಅರ್ಜುನನಿಗೆ ಮನವರಿಕೆ ಮಾಡಿಸುತ್ತಿದ್ದಾನೆ.",
  "2.12": "ನ ತು ಏವ ಅಹಮ್‌ ಜಾತು ನ ಅಸಮ್‌ ನ ತ್ವಮ್‌ ನ ಇಮೇ ಜನ ಅಧಿಪಾಃ |\nನ ಚ ಏವ ನ ಭವಿಷ್ಯಾಮಃ ಸರ್ವೇ ವಯಮ್‌ ಅತಃ ಪರಮ್‌..- ನಾನು ಹಿಂದೆ ಎಂದೂ ಇರದಿದ್ದವನಲ್ಲ. ಅಲ್ಲ\nನೀನೂ. ಅಲ್ಲ ಈ ಅರಸರೂ. ಇನ್ನು ಮುಂದೂ ನಾವೆಂದೂ ಇಲ್ಲವಾಗುವವರಲ್ಲ.\n\nಕೃಷ್ಣ ಇಲ್ಲಿ ಸಾವಿನ ಬಗ್ಗೆ ನಾವು ಏಕೆ ಚಿಂತಿಸಬೇಕಿಲ್ಲ ಎನ್ನುವ ಮಾತಿಗೆ ಪೂರಕವಾಗಿ, ಅದನ್ನು ಸಮರ್ಥಿಸುವ\nಮಾತನ್ನು ಹೇಳುತ್ತಾನೆ. ಆತ ಹೇಳುತ್ತಾನೆ: \"ನಾನು-ನೀನು ಈ ಎಲ್ಲಾ ರಾಜರು, ಹಿಂದೆ ಇದ್ದೆವು, ಇಂದು ಇದ್ದೇವೆ\nಹಾಗೂ ಮುಂದೆ ಕೂಡಾ ಇರುತ್ತೇವೆ. ದೇಹ ನಾಶವಾದಾಗ ಜೀವ ನಾಶವಾಗುವುದಿಲ್ಲ. ನಾನು ಹೇಗೆ\nಅನಾದಿನಿತ್ಯವೋ ಹಾಗೇ ಪ್ರತಿಯೊಂದು ಜೀವರು ಕೂಡಾ ಅನಾದಿನಿತ್ಯ. ಆತ್ಮವನ್ನು ಕೊಲ್ಲುವುದು ಅಸಾಧ್ಯ”\nಎಂದು. ಅನಂತ ಜೀವದ ಹರವು ಅನಂತ ಕಾಲದ ತನಕ ನಿರಂತರವಾಗಿರುತ್ತದೆ. ಆತ್ಮ ಎಂದೆಂದಿಗೂ\nಅಜರಾಮರ. ಪ್ರತಿಯೊಂದು ಜೀವಕ್ಕೆ ಅದರದ್ದೇ ಆದ ಸ್ವಭಾವವಿದೆ. ಜೀವ ಒಂದು ಬೀಜದಂತೆ. ಭಗವಂತ ಒಬ್ಬ\nತೋಟಗಾರನಂತೆ. ಆತ ಈ ಪ್ರಪಂಚವೆಂಬ ತೋಟದ ಸೃಷ್ಟಿ ಮಾಡಿ, ಈ ಜೀವವನ್ನು ಆ ತೋಟದಲ್ಲಿ ಬಿತ್ತಿ\nಅದಕ್ಕೊಂದು ಅಸ್ತಿತ್ವವನ್ನು ಕೊಟ್ಟ. ಪ್ರತಿಯೊಂದು ಜೀವ ಅದರ ಸ್ವಭಾವಕ್ಕನುಗುಣವಾಗಿ ಈ ಪ್ರಪಂಚದಲ್ಲಿ\nಬೆಳೆಯುತ್ತವೆ. ಒಂದು ಜೀವದ ಸ್ವಭಾವ ಇನ್ನೊಂದು ಜೀವದ ಸ್ವಭಾವಕ್ಕಿಂತ ಭಿನ್ನ. ಈ ಕಾರಣದಿಂದಾಗಿ ಈ\nಪ್ರಪಂಚ ಇಷ್ಟೊಂದು ವೈವಿದ್ಯಪೂರ್ಣ.\n",
  "2.13": "ದೇಹಿನಃ ಅಸ್ಮಿನ್‌ ಯಥಾ ದೇಹೇ ಕೌಮಾರಮ್‌ ಯೌವನಮ್‌ ಜರಾ।\n\nತಥಾ ದೇಹಾಂತರ ಪ್ರಾಪ್ತಿ ಧೀರಃ ತತ್ರ ನ ಮುಹ್ಯತಿ-ದೇಹದಲ್ಲಿರುವ ಜೀವಕ್ಕೆ ಈ ದೇಹದಲ್ಲೇ ಎಳೆತನ,\nಹರಯ, ಮುಪ್ಪು ಹೇಗೇ-ಹಾಗೇ ದೇಹದ ಬದಲಾವಣೆ ಕೂಡಾ. ಇಂತಹ ಸನ್ನಿವೇಶದಲ್ಲಿ ಧೀರನಾದವನು\nಕಂಗೆಡುವುದಿಲ್ಲ.\n\nದೇಹ ನಾಶವೆಂದರೆ ಸ್ವರೂಪ ನಾಶವಲ್ಲ. ಈ ದೇಹದಲ್ಲಿರುವ ಜೀವ ಪ್ರತೀಕ್ಷಣದಲ್ಲಿ ತನ್ನ ದೇಹ\nಪರಿವರ್ತನೆಯನ್ನು ಅನುಭವಿಸುತ್ತಿರುತ್ತದೆ. ಬಾಲ್ಯದಲ್ಲಿನ ದೇಹ ಯೌವನದಲ್ಲಿಲ್ಲ, ಯೌವನದಲ್ಲಿನ ದೇಹ\nಮುಪ್ಪಿನಲ್ಲಿಲ್ಲ. ಸತ್ತ ಬಳಿಕ ಮತ್ತೆ ಮರುಹುಟ್ಟಿನೊಂದಿಗೆ ಹೊಸ ದೇಹ. ಆದರೆ ನಮಗೆ ನಾವು ಎಲ್ಲಿಂದ ಬಂದೆವು\nಹಾಗೂ ಎಲ್ಲಿಗೆ ಹೋಗುತ್ತಿದ್ದೇವೆ ಎನ್ನುವ ಅರಿವು ಮಾತ್ರ ಇಲ್ಲ. ನಮಗೆ ತಿಳಿದಿರುವುದು ನಮ್ಮ ಈಗಿನ ಅಸ್ತಿತ್ವ\nಮಾತ್ರ. ದೇಹ ನಾಶವಾಗಿ ಹೊಸ ದೇಹ ಬರಬಹುದು. ಆದರೆ ಎಂದೂ ನಾಶವಾಗದ ಚೈತನ್ಯ ಈ 'ಜೀವ'. ಒಂದು\nದಿನ ನಾಶವಾಗುವ ಈ ದೇಹದ ಬಗ್ಗೆ ಧೀರನಾದವನು ಎಂದೂ ಅಳುವುದಿಲ್ಲ ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಇಲ್ಲಿ ಧೀರ\nಎಂದರೆ ಅರಿವಿನ ಆನಂದವನ್ನು ಅನುಭವಿಸುವ ಜ್ಞಾನಿ(ಧೀ+ರಃ). ಎಲ್ಲಿ ಜ್ಞಾನವಿದೆಯೋ ಅಲ್ಲಿ ದುಃಖವಿಲ್ಲ.\n",
  "2.14": "ಮಾತ್ರಾ ಸ್ಪರ್ಶಾಃ ತು ಕೌಂತೇಯ ಶೀತ ಉಷ್ಣ ಸುಖದುಃಖದಾಃ |\n\nಆಗಮ ಅಪಾಯಿನಃ ಅನಿತ್ಯಾಃ ತಾನ್‌ ತಿತಿಕ್ಷಸ್ವ ಭಾರತ -- ಕೌಂತೇಯ, ವಿಷಯ ಸಂಪರ್ಕಗಳೇ ತಂಪು-\nಬಿಸಿಗಳ, ಸುಖ-ದುಃಖಗಳ ಅನುಭವ ನೀಡುವಂಥವು. ಇವು ಬಂದು ಹೋಗುವಂಥವು. ನಿರಂತರವಾಗಿ\nಇರುವಂಥವಲ್ಲ. ಓ ಭಾರತಾ, ಅವುಗಳನ್ನು ಸಹಿಸಿಕೋ.\n\nನಾವು ಬಾಲ್ಯದ ದೇಹವನ್ನು ಕಳೆದುಕೊಂಡು ಯೌವನದ ದೇಹವನ್ನು ಪಡೆಯುತ್ತೇವೆ. ಯೌವನದ ದೇಹವನ್ನು\nಕಳೆದುಕೊಂಡು ಮುಪ್ಪಿನ ದೇಹವನ್ನು ಪಡೆಯುತ್ತೇವೆ. ಈ ಕಾರಣಕ್ಕಾಗಿ ಯಾರೂ ದುಃಖಿಸುವುದಿಲ್ಲ. ಆದರೆ\nಸಾವಿನಲ್ಲಿ 'ಕಾಣುವ' ಇನ್ನೊಂದು ದೇಹ ಇಲ್ಲವಾಗುತ್ತದೆ-ಆಗ ದುಃಖ. ಯಾವ ದೇಹದ ಮೂಲಕ ಭಾಂದವ್ಯದ\nನಂಟನ್ನು ಬೆಳೆಸಿಕೊಂಡಿರುತ್ತೇವೋ , ಅದು ಇಲ್ಲವಾಗುತ್ತದಲ್ಲಾ ಎನ್ನುವ ದುಃಖ ಸಾಮಾನ್ಯವಾಗಿ ನಮ್ಮನ್ನು\nಕಾಡುತದೆ.\n\nಜೀವನದಲ್ಲಿ ನಾವು ಅನುಭವಿಸುವ ಸುಖ ಮತ್ತು ದುಃಖದ ಮೂಲ “ಮಾತ್ರಾ ಸ್ಪರ್ಶಾ\". ಇದು ಎಲ್ಲವುದರ\nಮೂಲ. ನಾವು ಯಾವುದನ್ನು ನಮ್ಮ ಇಂದ್ರಿಯಗಳ ಮೂಲಕ ಗ್ರಹಿಸುತ್ತೇವೋ ಅದು ಮಾತ್ರೆ. ಶಬ್ದ, ಸ್ಪರ್ಶ,\nರೂಪ, ರಸ, ಗಂಧ ಇವೇ ನಮ್ಮ ಸುಖಿ-ದುಃಖಗಳಿಗೆ ಕಾರಣವಾದ ಐದು ಮಾತ್ರೆಗಳು.\n\nಸುಖ-ದುಃಖಗಳಿಗೆ ಒಂದು ವ್ಯವಸ್ಥೆ ಇಲ್ಲ. ಒಬ್ಬರಿಗೆ ಸುಖವಾದದ್ದು ಇನ್ನೊಬ್ಬರಿಗೆ ದುಃಖವಾಗಬಹುದು.\nವಿಷಯಗಳ ಸ್ಪರ್ಶದಿಂದ ಸುಖ-ದುಃಖ ಬರುತ್ತದೆ. ಅದು ಶೀತೊಷ್ಟದಂತೆ. ಮೊದಲು ಸುಖಕೊಟ್ಟ ವಸ್ತುವೇ\nಮುಂದೆ ದುಃಖವಾಗಿ ಪರಿಣಮಿಸಬಹುದು. ಸುಖ-ದುಃಖ ಜೀವದ ಧರ್ಮವಲ್ಲ. ಅದು ಬಂದು ಹೋಗುವಂತಾದ್ದು.\nಅದು ನಮ್ಮ ಮಾನಸಿಕ ಕಲ್ಪನೆಯ ಫಲ. \"ನನ್ನ\" ಎನ್ನುವುದು ದುಃಖಕ್ಕೆ ಮೂಲ ಕಾರಣ. ನಿದ್ದೆಯಲ್ಲಿ ನಮಗೆ\n\"ನನ್ನ\" ಎನ್ನುವುದು ಇಲ್ಲ. ಆದ್ದರಿಂದ ಎಂದೂ ನಿದ್ದೆಯಲ್ಲಿ ದುಃಖವಿಲ್ಲ. ಎಚ್ಚರ ಮತ್ತು ಕನಸಿನಲ್ಲಿ ಮಾತ್ರ ಈ\nಸಮಸ್ಯೆ. ನಿದ್ದೆಯಲ್ಲಿ ಎಲ್ಲವೂ ನಿರ್ಮಲ.\n\nನಾವೇ ನಮ್ಮ ಮಾನಸಿಕ ಭಾವನೆಗಳಿಂದ ಮತ್ತು ಅನುಭವಗಳಿಂದ ನಿರ್ಮಿಸಿಕೊಂಡಿರುವುದು ಈ ಸುಖ-ದುಃಖ.\nಇದರಿಂದ ಪಾರಾಗುವ ಉಪಾಯವನ್ನು ನಾವೇ ಕಲಿತುಕೊಳ್ಳಬೇಕು. ದುಃಖದ ಮೂಲದ ಅನ್ವೇಷಣೆ ಮಾಡಿದಾಗ\nದುಃಖ ಸಹ್ಯವಾಗುತ್ತದೆ. ನಾವು ನಮ್ಮ ಭಾವನೆಗಳನ್ನು ಸಹನೆ ಮಾಡಿಕೊಳ್ಳುವುದನ್ನು ಕಲಿತುಕೊಳ್ಳಬೇಕು.\nಯಾವುದು ಬಂತೋ ಅದನ್ನು ಸ್ವೀಕರಿಸುವುದನ್ನು ಕಲಿತುಕೊಳ್ಳಬೇಕು. ನನಗೆ 'ಅದೇ ಬೇಕು'; 'ಹೀಗೇ ಆಗಬೇಕು'\nಎನ್ನುವ ಚಿಂತನೆ ದುಃಖಕ್ಕೆ ಮೂಲ ಕಾರಣ. ಬಂದಿದ್ದನ್ನು ಬಂದಂತೆ ಎದುರಿಸುತ್ತೇನೆ ಎನ್ನುವ ಆತ್ಮಸ್ಥೈರ್ಯವಿದ್ದರೆ\nದುಃಖವಿಲ್ಲ.\n",
  "2.15": "ಯಂಹಿನ ವ್ಯಥಯಂತಿ ಏತೇ ಪುರುಷಂ ಪುರುಷ ಋಷಭ |\n\nಸಮ ದುಃಖ ಸುಖಮ್‌ ಧೀರಮ್‌ ಸಃ ಅಮೃತತ್ವಾಯ ಕಲ್ಪತೇ-ಓ ಗಂಡುಗಲಿಯೇ, ಯಾವ\nಶರೀರವನ್ನು [ಜ್ಞಾನಿಯನ್ನು] ಇವು ಕಾಡಲಾರವೋ, ಅವನು ಸುಖ-ದುಃಖವನ್ನು ಸಮನಾಗಿ ಕಾಣಬಲ್ಲ ಧೀರ.\nಅಂತವನು ಸಾವಿಲ್ಲದ ತಾಣವನ್ನು ಸೇರಲು ತಕ್ಕವನಾಗುತ್ತಾನೆ.\n\nಕೃಷ್ಣ ಮುಂದುವರಿದು ಹೇಳುತ್ತಾನೆ: “ಯಾವ ಪುರುಷನಿಗೆ “ಮಾತ್ರಾ ಸ್ಪರ್ಶ' ಕಾಡುವುದಿಲ್ಲವೋ ಅವನು ಸುಖ-\nದುಃಖವನ್ನು ಸಮನಾಗಿ ಕಾಣಬಲ್ಲ ಧೀರ” ಎಂದು. ಇಲ್ಲಿ \"ಪುರುಷ\" ಎನ್ನುವ ಪದ ಬಂದಿದೆ. 'ಪುರುಷ ಎಂದರೆ\nಗಂಡಸು; ಗಂಡಸರಿಗೆ ಮಾತ್ರ ಸಾಧನೆ-ಮೋಕ್ಷ'-ಎನ್ನುವ ಮೂಢನಂಬಿಕೆ ನಮ್ಮಲ್ಲಿದೆ. ಆದರೆ ಪುರುಷ ಎಂದರೆ\n“ಪುರದಲ್ಲಿ ಇರುವ ಜೀವ'. ಪುರ ಎಂದರೆ ಪೂರ್ಣವಾದ ದೇಹ. ಅಂದರೆ ಮಾನವ ದೇಹ. ಆದ್ದರಿಂದ ಪುರುಷ\nಎಂದರೆ ಮಾನವರು(Human being) ಅಥವಾ ಸಾಧಕ ಜೀವ. ಸ್ಥೂಲ ಶರೀರದಲ್ಲಿದ್ದೂ ಕೂಡಾ ಯಾರಿಗೆ\nಮಾತ್ರಾಸ್ಪರ್ಶದಿಂದ ಬರುವ ಸುಖ-ದುಃಖ ಬೇರೆ-ಬೇರೆಯಾಗಿ ಕಾಣುವುದಿಲ್ಲವೋ, ಆತ ಸುಖ ದುಃಖವನ್ನು\n\nಸಮನಾಗಿ ಕಾಣಬಲ್ಲ ಧೀರನೆನಿಸುತ್ತಾನೆ.\n\nಪುರುಷ ಎನ್ನುವುದಕ್ಕೆ ಇನ್ನೊಂದು ಅರ್ಥ 'ಎಲ್ಲಕ್ಕೆಂತ ದೊಡ್ಡವನಾದ ದೇವರನ್ನು ತಿಳಿದವ'. ನಮಗೆ ಸುಖ-ದುಃಖ\nಏಕೆ ಬರುತ್ತದೆ ಎನ್ನುವ ಜ್ಞಾನವಿದ್ದಾಗ, ನಾವು ಸುಖ ಬಂದಾಗ ಹಿಗ್ಗುವುದಿಲ್ಲ, ದುಃಖ ಬಂದಾಗ ಕುಗ್ಗುವುದಿಲ್ಲ.\nನಮ್ಮ ಜೀವನದಲ್ಲಿ ಬರುವ ಪ್ರತಿಯೊಂದು ಸುಖ-ದುಃಖಕ್ಕೂ ಒಂದು ಕಾರಣವಿದೆ. ಸುಖ-ದುಃಖ ಜೀವನದಲ್ಲಿ\nಬರುವ ಅಲೆಗಳು. ಇದರಲ್ಲಿ ಒಂದು ಬೇಕು, ಇನ್ನೊಂದು ಬೇಡ ಎನ್ನು ವ ಆಯ್ಕೆ ಸರಿಯಲ್ಲ. ಯಾವುದು ಬಂತೋ\nಅದಿರಲಿ ಎಂದು ಬದುಕಬೇಕು. ನಮಗೆ ಸುಖ-ದುಃಖವನ್ನು ಇನ್ನೊಬ್ಬರು ದ್ವೇಷದಿಂದ ಕೊಡುವುದಲ್ಲ. ಅದು ನಮ್ಮ\nಕರ್ಮ ಫಲ. ಸುಖ-ದುಃಖವನ್ನು ನಮಗೆ ಕೊಡುವವನು ಭಗವಂತ. ತಾಯಿ ತನ್ನ ಮಗುವಿನ ಉದ್ಧಾರಕ್ಕಾಗಿ ಹೇಗೆ\nಶಿಕ್ಷೆ ಕೊಡುತ್ತಾಳೋ, ಹಾಗೇ ಭಗವಂತ ನಮ್ಮ ಉದ್ಧಾರಕ್ಕಾಗಿ ನಮಗೆ ದುಃಖವನ್ನು ಕೊಡುತ್ತಾನೆ. ಇದು ಶಿಕ್ಷೆ\nಅಲ್ಲ-ಶಿಕ್ಷಣ. ಮನುಷ್ಯ ದುಃಖದಲ್ಲಿ ಬೆಳೆದಾಗ ಗಳಿಸುವ ಅನುಭವ ಎಂದೂ ಸುಖದಲ್ಲಿ ಗಳಿಸಲಾರ. ದುಃಖ\nಜೀವನದ ನಿಜವಾದ ಅನುಭವ. ಇದು ನಮಗೆ ಕೊಡುವ ದುಃಖದ ಹಿಂದೆ ಭಗವಂತನಿಟ್ಟ ಮಹಾ ಕಾರುಣ್ಯ. ಈ\nಜ್ಞಾನವಿದ್ದಾಗ ಮಾತ್ರ ನಮಗೆ ಸುಖ-ದುಃಖವನ್ನು ಏಕರೂಪದಲ್ಲಿ ಕಾಣುವ ಮನಃಸ್ಥಿತಿ ಬರುತ್ತದೆ. ಇಂತಹ\nಜ್ಞಾನವಿರುವವನು ಧೀರನಾಗುತ್ತಾನೆ. ತಿಳುವಳಿಕೆಯಿಂದ ಧೈರ್ಯ ಬರುತ್ತದೆ. ಯಾರು ಒಂದು ಜನ್ಮದಲ್ಲಿ ಸುಖ-\nದುಃಖವನ್ನು ಸಮನಾಗಿ ಕಾಣಬಲ್ಲ ತಿಳುವಳಿಕೆ ಹಾಗೂ ಧೈರ್ಯವನ್ನು ಗಳಿಸುತ್ತಾರೋ, ಅವರು ಮುಂದೆಂದೂ\nಈ ಸಂಸಾರ ಬಂಧದಲ್ಲಿ ಮರಳಿ ಹುಟ್ಟುವುದಿಲ್ಲ. ಇಂತಹ ಮಾನಸಿಕ ಸಮತೋಲನದ ಮೂಲಕ ಭಗವಂತನನ್ನು\nತಿಳಿದು ಮೋಕ್ಷವನ್ನು ಪಡೆಯತ್ತಾರೆ.",
  "2.16": "ನ ಅಸತಃ ವಿದ್ಯತೇ (ಅ)ಭಾವಃ ನ ಅಭಾವಃ ವಿದ್ಯತೇ ಸತಃ |\n\nಉಭಯೋಃ ಅಪಿ ದೃಷ್ಟಃ ಅಂತಃ ತು ಅನಯೋಃ ತತ್ವ ದರ್ಶಿಭಿಃ -- ಪ್ರಕೃತಿಗೂ ಅಳಿವಿಲ್ಲ; ಭಗವಂತನಿಗೂ\nಅಳಿವಿಲ್ಲ. [ಕೆಡುಕು ಮಾಡಿ ಒಳಿತಾಗದು, ಒಳಿತಿನಿಂದ ಕೆಡುಕಾಗದು].. ನಿಜವ ಕಂಡವರು ಈ ಎರಡರ\nತೀರ್ಮಾನವನ್ನು ಬಲ್ಲರು.\n\nಸುಖ-ದುಃಖವನ್ನು ಮೀರಿ ನಿಲ್ಲಬಹುದು. ಅದೊಂದು ಮಾನಸಿಕ ಸ್ಥಿತಿ. ಆದರೆ ಅರ್ಜುನನ ಪ್ರಶ್ನೆ- ತನ್ನ ಗುರು-\nಹಿರಿಯರನ್ನು ಕೊಲ್ಲುವುದು ಪಾಪವಲ್ಲವೇ? ಎನ್ನುವುದು. ಈ ಪ್ರಶ್ನೆಗೆ ಇಲ್ಲಿ ಉತ್ತರವಿದೆ. “ಸತ್ತಿನಿಂದ ಅಭಾವವಿಲ್ಲ,\nಅಸತ್ತಿನಲ್ಲಿ ಭಾವವಿಲ್ಲ” ಅಂದರೆ ಒಳ್ಳೆಯ ಕೆಲಸ ಮಾಡುವುದರಿಂದ ಎಂದೂ ದುಃಖವಿಲ್ಲ, ಕೆಟ್ಟ ಕೆಲಸ ಮಾಡಿದರೆ\nಸುಖವಿಲ್ಲ. ಕೆಲವೊಮ್ಮೆ ಕೆಟ್ಟ ಕೆಲಸ ಮಾಡುವವರು ಸುಖಪಡುತ್ತಿರುವಂತೆ ಭಾಸವಾದರೂ ಕೂಡಾ, ಅದು\nತಾತ್ಕಾಲಿಕ. ಅಧರ್ಮದ ಹಾದಿಯನ್ನು ತುಳಿದವ ಎಂದೂ ಯಶಸ್ಸನ್ನು ಕಾಣಲು ಸಾಧ್ಯವಿಲ್ಲ. ಮಹಾಭಾರತ\nಯುದ್ಧವನ್ನು ವಿಶ್ಲೇಷಣೆ ಮಾಡಿದರೆ ಅಲ್ಲಿ ಯುದ್ಧಕ್ಕೆ ಕಾರಣರಾದವರು ಪಾಂಡವರಲ್ಲ. ಪಾಂಡವರು ಧರ್ಮ\nರಕ್ಷಣೆಯ ಹೊಣೆಗಾರಿಕೆಯಿಂದ ಯುದ್ಧಕ್ಕೆ ಸಜ್ಜಾಗಿರುವುದು. ಇಲ್ಲಿ ಕೃಷ್ಣ ಸ್ಪಷ್ಟವಾಗಿ ಹೇಳುತ್ತಾನೆ: “ಒಳ್ಳೆಯ ಕೆಲಸ\nಮಾಡುವಾಗ ಯಾರ ಭಯವೂ ಬೇಡ ಹಾಗೂ ಅದರಿಂದ ದುಃಖವಿಲ್ಲ” ಎಂದು. ಧರ್ಮ ರಕ್ಷಣೆಯ ಹಾದಿಯಲ್ಲಿ\n\n'ನನ್ನವರು' ಎನ್ನುವುದು ಸಲ್ಲದು. ಜಗತ್ತಿನ ತತ್ವವನ್ನು ಸಾಕ್ಷಾತ್ಕಾರ ಮಾಡಿಕೊಂಡ ಜ್ಞಾನಿಗಳು ಕಂಡುಕೊಂಡ\nಕೊನೆಯ ಸತ್ಯವಿದು.\n\nಮಹಾಭಾರತದ ಪ್ರತಿಯೊಂದು ಶ್ಲೋಕಕ್ಕೂ ಹತ್ತು ಅರ್ಥಗಳಿವೆಯಂತೆ. ಮೇಲಿನ ಶ್ಲೋಕವನ್ನು ನಾವು\nಇನ್ನೊಂದು ಆಯಾಮದಲ್ಲಿ ನೋಡಿದರೆ- \"ನ ಅಸತಃ ಅಭಾವಃ ಸತಃ ಅಭಾವಃ ನ ವಿದ್ಯತಿ” ಅಂದರೆ ಸತ್ತಿಗೂ\nಅಭಾವವಿಲ್ಲ ಅಸತ್ತಿಗೂ ಅಭಾವವಿಲ್ಲ ಎಂದರ್ಥ. ಅಸತ್‌ ಎಂದರೆ ಸ್ಥೂಲ ಪ್ರಪಂಚಕ್ಕೆ ಕಾರಣವಾಗಿರುವ,\nಸೂಕ್ಷ್ಮವಾಗಿರುವ ಮೂಲಪ್ರಕೃತಿ. ಪ್ರಕೃತಿ ಅನಾದಿನಿತ್ಯ. ಈ ಪ್ರಕೃತಿಯನ್ನು ಸೃಷ್ಟಿಮಾಡಿದ ಭಗವಂತ(ಪುರುಷ)\nಅನಾದಿನಿತ್ಯ. ಪ್ರಕೃತಿ ಮತ್ತು ಪುರುಷನಿಗೆ ಅಧೀನವಾಗಿರುವ ಜೀವ ಕೂಡಾ ಅನಾದಿನಿತ್ಯ. ಜೀವಕ್ಕೆಈ ಸ್ಥೂಲ\nದೇಹ ಬರುವ ಮೊದಲೂ ಜೀವ ಇತ್ತು, ಹಾಗೂ ಮುಂದೆ ಕೂಡಾ ಇರುತ್ತದೆ. ಪಾಂಚಭೌತಿಕ ಶರೀರದಲ್ಲಿ ಜೀವ\nಕೇವಲ ಅತಿಥಿ. ಹೀಗಿರುವಾಗ ದೇಹಾಭಿಮಾನ ಸಲ್ಲದು.",
  "2.17": "ಅವಿನಾಶಿ ತು ತತ್‌ ವಿದ್ಧಿ ಯೇನ ಸರ್ವಮ್‌ ಇದಮ್‌ ತತಮ್‌ |\nವಿನಾಶಮ್‌ ಅವ್ಯಯಸ್ಯ ಆಸ್ಕ ನ ಕಶ್ಚಿತ್‌ ಕರ್ತುಮ್‌ ಅರ್ಹತಿ--ಯಾವುದು ಈ ಎಲ್ಲವನ್ನು ವ್ಯಾಪಿಸಿದೆ ಅದು\nಅಳಿವಿಲ್ಲದ್ದು ಎಂದು ತಿಳಿ. ಬದಲಾಗದ “ಅವನ' ಅಳಿವು ಯಾರ ಅಳಿವಿಗೂ ಎಟಕುವುದಲ್ಲ.\n\nಯಾವುದು ಎಲ್ಲಾ ಕಡೆ ವ್ಯಾಪಿಸಿದೆಯೋ ಅದಕ್ಕೆ ನಾಶವಿಲ್ಲ. ರೂಪಾತ್ಮಕ ಪ್ರಪಂಚದಂತೆ ನಾಮಾತ್ಮಕ\nಪ್ರಪಂಚವಿದೆ. ಅದು ನಿತ್ಯ. ಇಲ್ಲಿ ನಾಮಾತ್ಮಕ ಎಂದರೆ 'ಅಕ್ಷರ' ; ಅ ದಿಂದ ಕ್ಷ ತನಕ ಇರುವ ಐವತ್ತೊಂದು\nವರ್ಣಗಳು. ಈ ಐವತ್ತೊಂದು ಅಕ್ಷರಗಳೇ ಮೂಲಭೂತವಾಗಿರುವ ಇಡೀ ಶಬ್ದ ಪ್ರಪಂಚ. ಅದು ನಾಶ\nಮಾಡಲಾಗದ ತತ್ವ. ಆದ್ದರಿಂದ ಭಗವಂತ, ಪ್ರಕೃತಿ, ಜೀವ ಹಾಗೂ ಈ ಎಲ್ಲಾ ತತ್ವಗಳನ್ನು ಪ್ರತಿಪಾದಿಸುವ\nಶಬ್ದ[ವೇದ] ಅನಾದಿನಿತ್ಯ. ಇದನ್ನು ಯಾರಿಂದಲೂ ನಾಶ ಮಾಡಲು ಸಾಧ್ಯವಿಲ್ಲ. ಈ ನಾಮಾತ್ಮಕ\nಪ್ರಪಂಚದಲ್ಲಿನ ವೇದ ವಾಜ್ಮಯನಾದ ಭಗವಂತ ಅವಿನಾಶಿ. ಆತನಿಗೆ ಸ್ವರೂಪ ನಾಶ, ದೇಹ ನಾಶ,\nದುಃಖಪ್ರಾಪ್ತಿ, ಅಪೂರ್ಣತ್ವ ಇಂತಹ ಯಾವುದೇ ರೀತಿಯ ನಾಶವಿಲ್ಲ. ಆತ ಕಾಲತಃ, ದೇಶತಃ, ಗುಣತಃ\nವ್ಯಾಪ್ತನಾಗಿರುವ ಅನಂತ ಸ್ವರೂಪ. ಆತ ಅವ್ಯಯ, ಯಾವ ವಿಕಾರ ಬದಲಾವಣೆಗೆ ಒಳಗಾಗದ, ಅನಾದಿನಿತ್ಯ\n\nಸ್ವರೂಪ.\n",
  "2.18": "ಅಂತವಂತ ಇಮೇ ದೇಹಾಃ ನಿತ್ಯಸ್ಯ ಉಕ್ತಾಃ ಶರೀರಿಣಃ |\n\nಅನಾಶಿನಃ ಅಪ್ರಮೇಯಸ್ಯ ತಸ್ಮಾತ್‌ ಯುಧ್ಯಸ್ವ ಭಾರತ-- ಅಳಿಯದ ಜೀವಕ್ಕೆ ಅಳಿವ ಈ ದೇಹಗಳ ನಂಟು.\nಏತರಿದಲೂ ಅವನಿಗೆ ಅಳಿವಿಲ್ಲ. ಅವನು ಎಲ್ಲೆಡೆ ತುಂಬಿದ ಭಗವಂತನ ಪಡಿಯಚ್ಚು. ಓ ಭಾರತಾ, ಆದ್ದರಿಂದ\n[ಅಳಿವಿರದ ಅಳವಿಗೆಟುಕದ ಭಗವಂತನ ಪೂಜೆಯೆಂದು। ಹೋರಾಡು.\n\nಭೌತಿಕ ಶರೀರ ಅಂತವಂತ(ನಾಶವಾಗುವಂತಾದ್ದು). ಕೇವಲ ಕಣ್ಣಿಗೆ ಕಾಣುವ ಸ್ಥೂಲ ಶರೀರ ಮಾತ್ರ\nನಾಶವಾಗುವುದೇ ಹೊರತು ಆಅತ್ಮವಲ್ಲ. ಏಕೆಂದರೆ ಜೀವ ಭಗವಂತನ ಪಡಿಯಚ್ಚು. ಅದು ಸರ್ವವ್ಯಾಪಿ\nಭಗವಂತನ ಪ್ರತಿಬಿಂಬ. ಆದ್ದರಿಂದ ಎಲ್ಲಾ ಕಡೆ ಇರುವ ಭಗವಂತನ ಪ್ರತಿಬಿಂಬವಾದ ಈ ಜೀವ ನಿತ್ಯ. ಇಲ್ಲಿ ಕೃಷ್ಣ\nಅರ್ಜುನನಿಗೆ ಹೇಳುತ್ತಾನೆ: \"ಸಾಮ್ರಾಟನಾಗಬೇಕು ಎನ್ನು ವ ಸ್ವಾರ್ಥದಿಂದಾಗಲೀ, ದುರ್ಯೋಧನನ ಮೇಲಿನ\nದ್ವೇಷದಿಂದಾಗಲೀ ಹೋರಾಡದೇ, \"ಅನ್ಯಾಯದ ವಿರುದ್ಧ ಹೋರಾಟ ಭಗವಂತನ ಪೂಜೆ' ಎಂಬಂತೆ ಯುದ್ಧ\nಮಾಡು\" ಎಂದು.\n\nನಾವು. ನಮ್ಮ ದೈನಂದಿನ ಜೀವನದಲ್ಲಿ ಮಾಡುವ ಪ್ರತಿಯೊಂದು ಕರ್ಮ ಕೂಡಾ ಹೀಗೆ. ಅದು ಭಗವಂತನ\nಅರ್ಪಣಾ ರೂಪದಲ್ಲಿರಬೇಕು. ನಮಗೆ ದೇಹ ಕೊಟ್ಟಿದ್ದು ಭಗವಂತ. ಆದ್ದರಿಂದ ಆ ದೇಹ ಹೋದಾಗ ಅಳುವ\nಅಗತ್ಯವಿಲ್ಲ. ನಮ್ಮ ಪ್ರತಿಯೊಂದು ಕರ್ತವ್ಯವನ್ನು ಭಗವಂತನ ಪೂಜೆ ಎಂದು ಮಾಡಿ, ಸಾವಿಗೆ ಅಂಜದೆ\nಬದುಕಿದಾಗ ಈ ಜೀವನ ಸಾರ್ಥಕ.\n",
  "2.19": "ಯಃ ಏನಮ್‌ ವೇತ್ತಿ ಹಂತಾರಮ್‌ ಯಃ ಚ ಏನಮ್‌ ಮನ್ಯತೇ ಹತಮ್‌ |\n\nಉಭೌ ತೌ ನ ವಿಜಾನೀತಃ ನ ಅಯಮ್‌ ಹಂತಿ ನ ಹನ್ಯತೇ --ಯಾರು ಇವನನ್ನು 'ಕೊಲ್ಲುವವನು' ಎಂದು\nತಿಳಿದಿದ್ದಾನೊ ಮತ್ತು ಯಾರು ಇವನನ್ನು 'ಸತ್ತವನು' ಎಂದು ತಿಳಿದಿದ್ದಾನೊ-ಆ ಇಬ್ಬರೂ ತಿಳಿದವರಲ್ಲ. ಇವನು\nಕೊಲ್ಲುವುದಿಲ್ಲ ಮತ್ತು ಸಾಯುವುದಿಲ್ಲ.\n\nಜೀವವನ್ನು ಕೊಲ್ಲಬಹುದು/ಕೊಲ್ಲುತ್ತೇನೆ ಎಂದು ಭಾವಿಸುವವರಿಗೆ ಹಾಗೂ ಅದು ನಾಶವಾಯಿತು/ಕೊಲ್ಲಲ್ಪಟ್ಟಿತು\nಎನ್ನು ವವರಿಗೆ ತಿಳುವಳಿಕೆ ಇಲ್ಲ. ಏಕೆಂದರೆ ಜೀವ ಕೊಲ್ಲುವುದೂ ಇಲ್ಲ, ಕೊಲ್ಲಲ್ಪಡುವುದೂ ಇಲ್ಲ. ಆತ್ಮವನ್ನು\nಕೊಲ್ಲುವುದು ಸಾಧ್ಯವೇ ಇಲ್ಲ. ನಮಗೆ ಸಾಯುವುದು ಅಥವಾ ಸತ್ತಿತು ಎಂದು ಕಾಣುವುದು ಭೌತಿಕ ಶರೀರ\nಮಾತ್ರ. ಜೀವನಿಗೆ ದೇಹದ ಮೂಲಕ ಕೂಡಾ ಕೊಲ್ಲುವ ಅಥವಾ ಸಾಯುವ ಸ್ವಾತಂತ್ರ್ಯ ಇಲ್ಲ. ಇಲ್ಲಿ ಅರ್ಜುನನಿಗೆ\n'ಕೌರವರು ನನ್ನ ಕೈಯಿಂದ ಸಾಯುತ್ತಾರೆ' ಎನ್ನುವುದು ಕೇವಲ ಭ್ರಮೆ. ಸೃಷ್ಟಿ-ಸಂಹಾರ ಕರ್ತನಾದ ಭಗವಂತನ\nಇಚ್ಛೆ ಇಲ್ಲದೆ ಯಾವುದೂ ನಡೆಯುವುದಿಲ್ಲ. ಆತನ ಇಚ್ಛೆಗೆ ವಿರುದ್ಧವಾಗಿ ನಾವು ಏನೂ ಮಾಡಲು ಸಾಧ್ಯವಿಲ್ಲ.\n",
  "2.20": "ನ ಜಾಯತೇ ಮ್ರಿಯತೇ ವಾ ಕದಾಚಿತ್‌ ನ ಅಯಮ್‌ ಭೂತ್ವಾ ಭವಿತಾ ವಾನ ಭೂಯಃ |\n\nಅಜಃ ನಿತ್ಯಃ ಶಾಶ್ವತಃ ಅಯಮ್‌ ಪುರಾಣಃ ನ ಹನ್ಯತೇ ಹನ್ಯಮಾನೇ ಶರೀರೇ -. ಈ ಜೀವ ಎಂದೂ\nಹುಟ್ಟುವುದಿಲ್ಲ; ಸಾಯುವುದೂ ಇಲ್ಲ. ಭಗವಂತನ ಅರಿವಿನಂತೆ ಹುದುಗಿದ್ದು ಮತ್ತಾಗುವವನೂ ಅಲ್ಲ. ಇವನು\nಹುಟ್ಟಿರದ, ಸಾವಿರದ, ಮಾರ್ಪಡದ-ಭಗವಂತನ ಪಡಿಯಚ್ಚು.[೫ ಪರಮ ಪುರುಷ ಎಂದೂ ಹುಟ್ಟುವುದಿಲ್ಲ;\nಸಾಯುವುದೂ ಇಲ್ಲ. ಸ್ವರೂಪದಿಂದಿದ್ದು ದೇಹದಿಂದ ಹುಟ್ಟುತ್ತಾನೆ ಎನ್ನುವುದೂ ಸಲ್ಲ. ಈ ಜೀವ ಕೂಡಾ ಹುಟ್ಟದ,\nಸಾಯದ, ಬದಲಾಗದ ತತ್ವ.] ದೇಹದಿಂದ ದೇಹಕ್ಕೆ ಅಲೆವ ಈ ಜೀವ ದೇಹ ಅಳಿದರೂ ತಾನಳಿಯುವುದಿಲ್ಲ.\n\nಇಲ್ಲಿ ಕೃಷ್ಣ 'ಜೀವಸ್ವರೂಪ' ಅಂದರೆ ಏನೆಂದು ವಿವರಿಸಿದ್ದಾನೆ. ಈ ಜೀವ ಸ್ವರೂಪತಃ ಎಂದೂ ಹುಟ್ಟುವುದಿಲ್ಲ\nಮತ್ತು ಎಂದೂ ನಾಶವಾಗುವುದಿಲ್ಲ. ಅದು ಸದಾ ಏಕರೂಪದಲ್ಲಿರುತ್ತದೆ. ಏಕೆಂದರೆ ಜೀವಸ್ವರೂಪ ಭಗವಂತನ\nಪ್ರತಿಬಿಂಬ. ಭಗವಂತನಿಗೆ ಹುಟ್ಟಿಲ್ಲ. ಅವನು ನಿತ್ಯ ಹಾಗೂ ಶಾಶ್ವತ. ಜೀವ ಸದಾ ಶರೀರದಿಂದ ಶರೀರಕ್ಕೆ\nಸಂಚರಿಸುತ್ತಿರುತ್ತದೆ(ಪುರ-ಅಣ). ಆದರೆ ದೇಹ ಬದಲಾದಂತೆ ಜೀವಸ್ವರೂಪ ಬದಲಾಗುವುದಿಲ್ಲ. ಭೌತಿಕ\nಶರೀರಕ್ಕೆ ಮುದಿತನವಿದ್ದಂತೆ ಜೀವ ಸ್ವರೂಪಕ್ಕೆ ಮುದಿತನವಿಲ್ಲ. ಅದು ಸದಾ ಏಕರೂಪದಲ್ಲಿರುತ್ತದೆ. ಆದರೆ\nಪ್ರಭಾವದಿಂದ ಬಂದ ನಂಬಿಕೆ ಬದಲಾಗಬಹುದು. ಉದಾಹರಣೆಗೆ ಒಂದು ಜನ್ಮದಲ್ಲಿ ನಾಸ್ತಿಕನಾಗಿರುವವ\nಇನ್ನೊಂದು ಜನ್ಮದಲ್ಲಿ ಪೂರ್ಣ ಆಸ್ತಿಕನಾಗಬಹುದು. ಸ್ವಭಾವ ವಿಶಿಷ್ಟನಾದ ಜೀವ ಎಂದೂ ಬದಲಾಗದೇ,\nನಾಶವಾಗದೇ ಉಳಿಯುತ್ತಾನೆ.\n",
  "2.21": "ವೇದ ಅವಿನಾಶಿನಮ್‌ ನಿತ್ಯಮ್‌ ಯಃ ಏನಮ್‌ ಅಜಮ್‌ ಅವ್ಯಯಮ್‌ |\n\nಕಥಮ್‌ ಸಃ ಪುರುಷಃ ಪಾರ್ಥ ಕಮ್‌ ಘಾತಯತಿ ಹಂತಿ ಕಮ್‌-ಓ ಪಾರ್ಥಾ, ಹುಟ್ಟು-ಸಾವುಗಳಿರದ,\nಮಾರ್ಪಡದ, ಏತರಿಂದಲೂ ಅಳಿಯದ ಈ ಜೀವನನ್ನು[ಶರೀರದಿಂದಲೂ ಅಳಿವಿರದ ಭಗವಂತನನ್ನು] ಬಲ್ಲ\nಜೀವಿ, ಯಾರನ್ನು ಹೇಗೆ ಕೊಲ್ಲಿಸುವುದು ? ಯಾರನ್ನು ಹೇಗೆ ಕೊಲ್ಲುವುದು?\n\nದೋಷ ಸಂಬಂಧವಿಲ್ಲದ, ನಿತ್ಯವಾದ, ಎಂದೂ ಬದಲಾಗದ ಜೀವ ಸ್ವರೂಪವನ್ನು ಯಾರು ತಿಳಿಯುತ್ತಾರೋ,\nಅಂತಹ ಮಾನವ ಯಾರನ್ನು ಕೊಲ್ಲುವುದು ಅಥವಾ ಕೊಲ್ಲಿಸುವುದು ಹೇಗೆ ಸಾಧ್ಯ? ಸ್ವರೂಪತಃ ಜೀವನಿಗೆ\nನಾಶವಿಲ್ಲ ಎಂದು ತಿಳಿದಾಗ, ಸ್ಥೂಲ ಪ್ರಪಂಚದಲ್ಲಿ ಹುಟ್ಟು-ಸಾವು ಭಗವಂತನ ಇಚ್ಛೆಯಂತೆ ನಡೆಯುತ್ತಿದೆ ಎಂದು\n\nತಿಳಿದ ಮೇಲೆ, ಯಾರು ಯಾರನ್ನು ಕೊಲ್ಲುವುದು ಅಥವಾ ಕೊಲ್ಲಿಸುವುದು? ಹುಟ್ಟು-ಸಾವಿನ ಹಿಂದಿರುವ ಭಗವದ್‌\nಶಕ್ತಿಯನ್ನು ನಾವು ಅರಿತುಕೊಳ್ಳಬೇಕು ಅಷ್ಟೆ.\nಜೀವಕ್ಕೆ ಅಳಿವಿಲ್ಲ, ಅದಕ್ಕೆ ಹುಟ್ಟು-ಸಾವು ಎನ್ನು ವುದಿಲ್ಲ. ಹಾಗಿದ್ದರೆ ನಾವು ಪ್ರಾಪಂಚಿಕವಾಗಿ ಕಾಣುವ ಹುಟ್ಟು-\nಸಾವನ್ನು ಅರ್ಥ ಮಾಡಿಕೊಳ್ಳುವುದು ಹೇಗೆ? ಈ ಪ್ರಶ್ನೆಗೆ ಕೃಷ್ಣ ಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ಉತ್ತರಿಸಿದ್ದಾನೆ.",
  "2.22": "ವಾಸಾಂಸಿ ಜೀರ್ಣಾನಿ ಯಥಾ ವಿಹಾಯ ನವಾನಿ ಗೃಹ್ಣಾತಿ ನರಃ ಅಪರಾಣಿ |\n\nತಥಾ ಶರೀರಾಣಿ ವಿಹಾಯ ಜೀರ್ಹಾನಿ ಅನ್ಯಾನಿ ಸಂಯಾತಿ ನವಾನಿ ದೇಹೀ -- ಮನುಷ್ಯ ಹಳೆಯ\nಬಟ್ಟೆಬರೆಗಳನ್ನು ಬಿಸುಟು ಬೇರೆ ಹೊಸತನ್ನು ಉಡುತ್ತಾನೆ ಹೇಗೆಯೋ ಹಾಗೇ-ಜೀವ ಒಂದು ದೇಹವನ್ನು ಬಿಟ್ಟು\nಬೇರೆ ಹೊಸ ದೇಹವನ್ನು ಪಡೆಯುತ್ತಾನೆ.\n\nನಾವು ಉಟ್ಟ ಬಟ್ಟೆ ಹಳೆಯದಾದಾಗ ಹೇಗೆ ಅದನ್ನು ಬದಲಿಸುತ್ತೇವೋ-ಹಾಗೇ, ಜೀವ ಒಂದು ದೇಹವನ್ನು ಬಿಟ್ಟು\nಇನ್ನೊಂದು ದೇಹವನ್ನು ಪಡೆಯುತ್ತಾನೆ. ಇಲ್ಲಿ ಒಂದು ವಿಶೇಷವೆಂದರೆ ಹೇಗೆ ತಾಯಿ ತನ್ನ ಮಗುವಿಗೆ\nತನ್ನಿಚ್ಚೆಯಂತೆ ಬಟ್ಟೆ ಬದಲಿಸುತ್ತಾಳೋ ಹಾಗೆ ಭಗವಂತ ಜೀವದ ದೇಹ ಬದಲಿಸುತ್ತಾನೆ. ಜೀವನಿಗೆ ಸ್ವತಃ ದೇಹ\nಬದಲಿಸುವ ಸ್ವಾತಂತ್ರ್ಯ ಇರುವುದಿಲ್ಲ. ಇದಕ್ಕೆ ಒಂದು ಅಪವಾದ ಎಂದರೆ ಆತ್ಮ ಸಾಕ್ಷಾತ್ಕಾರವಾದ\nಯೋಗಿಗಳು. ಅವರು ಭಗವಂತನ ಅನುಗ್ರಹದಿಂದ ಸ್ವ-ಇಚ್ಛೆಯಂತೆ ದೇಹ ಬದಲಿಸುವ ಶಕ್ತಿಯನ್ನು\nಪಡೆದಿರುತ್ತಾರೆ. [ಈ ಬಗ್ಗೆ ಸ್ವಾಮಿರಾಮ್‌ ಅವರು ಬರೆದಿರುವ \"Living with Himalayan Masters\" ಎನ್ನುವ\nಪುಸ್ತಕದಲ್ಲಿ ಅನೇಕ ನೈಜ ದೃಷ್ಟಾಂತಗಳನ್ನು ಕಾಣಬಹುದು. ಇಂತಹ ಮಹಾನ್‌ ಯೋಗಿಗಳನ್ನು ಬಿಟ್ಟರೆ\nಇತರರಿಗೆ ಸ್ವ-ಇಚ್ಛೆಯಂತೆ ದೇಹ ಬದಲಿಸುವ ಸ್ವಾತಂತ್ರ್ಯ ಇಲ್ಲ. ಆದ್ದರಿಂದ ಭೌತಿಕವಾಗಿ ಹುಟ್ಟು -ಸಾವು ಎಂದರೆ\nಉಟ್ಟ ಬಟ್ಟೆಯನ್ನು ಕಳಚಿ ಹೊಸ ಬಟ್ಟೆಯನ್ನು ತೊಡಿಸಿದಂತೆ. ಸ್ವರೂಪತಃ ಜೀವಕ್ಕೆ ಎಂದೂ ಹುಟ್ಟು-ಸಾವು\nಅನ್ನು ವುದಿಲ್ಲ ಹಾಗೂ ಹೊಸ ಶರೀರದಿಂದ ಅದರ ಮೂಲಸ್ವಭಾವ ಬದಲಾಗುವುದಿಲ್ಲ.\n\nಹಾಗಾದರೆ ಆತ್ಮವನ್ನು ನಾಶ ಮಾಡಲು ಸಾದ್ಯವೇ ಇಲ್ಲವೋ? ಎಂದೆಂದಿಗೂ ಇಲ್ಲ ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ ಮುಂದಿನ\nಶ್ಲೋಕದಲ್ಲಿ.\n",
  "2.23": "ನ ಏನಮ್‌ ಛಿಂದಂತಿ ಶಸ್ತ್ರಾಣಿ ನ ಏನಮ್‌ ದಹತಿ ಪಾವಕಃ |\nನ ಚ ಏನಮ್‌ ಕ್ಲೇದಯಂತಿ ಅಪಃ ನ ಶೋಷಯತಿ ಮಾರುತಃ -- ಈ ಜೀವನನ್ನು (ಭಗವಂತನನ್ನು)\nಆಯುಧಗಳು ತುಂಡರಿಸವು. ಇವನನ್ನು ಬೆಂಕಿ ಸುಡದು. ಇವನನ್ನು ನೀರು ನೆನೆಸದು, ಗಾಳಿ ಒಣಗಿಸದು.\n\nಯಾವುದೇ ಒಂದು ವಸ್ತುವನ್ನು ನಾಶಮಾಡಲು ಇರುವ ಮುಖ್ಯ ಅಸ್ತ್ರ ನಾಲ್ಕು. ಮಣ್ಣು(ಘನ ಆಯುಧ), ನೀರು,\nಬೆಂಕಿ ಹಾಗೂ ಗಾಳಿ. ಜೀವ-ಸೂಕ್ಷ್ಮರಲ್ಲಿ ಸೂಕ್ಷ್ಮ. ಶಾಸ್ತ್ರಕಾರರು ಹೇಳುವಂತೆ ಕುದುರೆಯ ಬಾಲದ ಒಂದು\nಕೂದಲಿನ ತುತ್ತ ತುದಿಯನ್ನು ಹತ್ತು ಸಾವಿರ ಭಾಗಗಳಾಗಿ ವಿಂಗಡಿಸಿದರೆ ಸಿಗುವ ಒಂದು ಭಾಗ ಎಷ್ಟು\nಗಾತ್ರದ್ದೋ ಅಷ್ಟು ಗಾತ್ರದಲ್ಲಿರುತ್ತದೆ ಜೀವ. ಇಂತಹ ಜೀವವನ್ನು ಯಾವುದೇ ಆಯುಧ ತುಂಡರಿಸಲು\nಸಾಧ್ಯವಿಲ್ಲ. ಬೆಂಕಿ ಜೀವನನ್ನು ಸುಡಲಾರದು. ನೀರಿನಿಂದ ಜೀವ ಒದ್ದೆಯಾಗದು. ಗಾಳಿ ಜೀವನನ್ನು ಒಣಗಿಸದು.\nಸೂಕ್ಷ್ಮಾತಿ ಸೂಕ್ಷ್ಮವಾದ ಜೀವನನ್ನು ಯಾವ ಆಯುಧವೂ ನಾಶ ಮಾಡಲಾರವು.\n\nಇಲ್ಲಿ ನಮಗೆ ಇನ್ನೊಂದು ಪ್ರಶ್ನೆ ಮೂಡುತ್ತದೆ. “ಇಂದು ನಾಶ ಮಾಡಲು ಅಸಾಧ್ಯವಾದ ಜೀವ ಎಂದೆಂದೂ\nನಾಶವಾಗದೇ ಇರುತ್ತದೆಯೇ?” ಎಂದು. ಹೌದು ಎನ್ನು ತ್ತಾನೆ ಕೃಷ್ಣ ಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ.",
  "2.24": "ಅಚ್ಛೇದ್ಯಃ ಅಯಮ್‌ ಅದಾಹ್ಯಃ ಅಯಮ್‌ ಅಕ್ಲೇದ್ಯಃ ಅಶೋಷ್ಯಃ ಏವ ಚ।\n\nನಿತ್ಯಃ ಸರ್ವಗತಃ ಸ್ಥಾಣು ಆಚಲಃ ಅಯಮ್‌ ಸನಾತನಃ -- ಈ ಜೀವನನ್ನು ಕಡಿಯಲಾಗದು. ಇವನನ್ನು\nಸುಡಲಾಗದು. ನೆನೆಸಲಾಗದು; ಒಣಗಿಸಲೂ ಆಗದು. ಎಂದೆಂದೂ ಎಲ್ದೆಡೆ ಹಬ್ಬಿರುವ, ಏತರಿಂದಲೂ\nಮಾರ್ಪಡದ, ಅವಿಚಲನಾದ, ಪುರಾಣಪುರುಷನ ಪಡಿಯಚ್ಚು ಇವನು.[ಎಲ್ಲೆಡೆ ಹಬ್ಬಿರುವ ಭಗವಂತನನ್ನು\nಎಂದೆಂದೂ ಹೊಂದಿರುವ ಅಣುರೂಪಿ. ಇವನು ಏತರಿಂದಲೂ ಮಾರ್ಪಡದ ನಿಯತಿಗೆ ಬದ್ಧ ; ವೇದದ ವಿಧಿ-\nನಿಷೇಧಗಳಿಗೆ ಕೂಡಾ].\n\nಜೀವನನ್ನು ಇಂದಲ್ಲ, ಮುಂದೆಂದೂ ಯಾರಿಂದಲೂ ನಾಶಮಾಡಲು ಸಾದ್ಯವಿಲ್ಲ. ಏಕೆಂದರೆ ಆತ ತನ್ನ\nಗುಣಧರ್ಮದಿಂದ ಎಂದೂ ಬದಲಾಗದ, ಸರ್ವಗತನಾದ, ವಿಚಲಿತನಾಗದ-ಭಗವಂತನ ಪಡಿಯಚ್ಚು. ಯಾವ\nಆಯುಧಕ್ಕೂ ನಿಲುಕದೆ ಎಲ್ಲಾ ಕಾಲದಲ್ಲೂ ಏಕರೂಪನಾಗಿರುವ, ಎಲ್ಲಾ ಕಡೆ ಸ್ಥಿರವಾದ, ಬದಲಾವಣೆ ಇಲ್ಲದೆ\nಇರುವ ಗುಣಧರ್ಮ ಜೀವನಿಗಿದೆ. ಜೀವ ಸನಾತನ. ಅಂದರೆ ನಾತನದಿಂದ ಸಹಿತನಾದವ. ಇಲ್ಲಿ 'ನಾತನ'\nಎಂದರೆ 'ನಾದನ'. ಅಂದರೆ ವೇದನಾದ. ಜೀವ ವೇದನಾದದಿಂದ ಸಹಿತನಾಗಿ, ಸಮಸ್ತ ವೇದ ಪ್ರತಿಪಾದ್ಯನಾದ\nಭಗವಂತನ ಮಡಿಲಲ್ಲಿ ವೇದದ ವಿಧಿ-ನಿಷೇಧಗಳಿಗೆ ಬದ್ಧನಾಗಿರುತ್ತಾನೆ. ಅದು ಸರ್ವಗತನಾದ ಭಗವಂತನನ್ನು\nಆಶ್ರಯಿಸಿರುವ ಮಹತ್ತಾದ ಅಣು.\n",
  "2.25": "ಅವ್ಯಕ್ತಃ ಅಯಮ್‌ ಅಚಿಂತ್ಯಃ ಅಯಮ್‌ ಅವಿಕಾರ್ಯಃ ಅಯಮ್‌ ಉಚ್ಯತೇ\n\nತಸ್ಮಾತ್‌ ಏವಮ್‌ ವಿದಿತ್ವಾ ಏನಮ್‌ ನ ಅನುಶೋಚಿತುಮ್‌ ಅರ್ಹಸಿ -- ಭಗವಂತ ಕಣ್ಣಿಗೆ ಕಾಣದವನು; ಇವನು\nಚಿಂತನೆಗೆ ನಿಲುಕದವನು; ಇವನು ಬದಲಾಗದವನು-ಎಂದು ವೇದ ಸಾರುತ್ತದೆ. ಅದರಿಂದ ಅವನ[ಮತ್ತು\nಜೀವನ] ಪರಿಯನ್ನು ಹೀಗೆ ಅರಿತ ಮೇಲೆ ಕೊರಗುವುದು ತರವಲ್ಲ.\n\nಭಗವಂತ ಅವ್ಯಕ್ತ. ಆತನ ಪ್ರತಿಬಿಂಬವಾದ ಜೀವ ಭೌತಿಕ ಶರೀರದಲ್ಲಿದ್ದರೂ ಕೂಡಾ ಅವ್ಯಕ್ತ. ಈ ಕಾರಣದಿಂದ\nಭಗವಂತ ಹಾಗೂ ಜೀವ ನಮ್ಮ ಚಿಂತನೆಗೆ ನಿಲುಕದ್ದು. ನಾನು ಯಾರು? ಎಲ್ಲಿಂದ ಬಂದೆ ? ನಾನೇನು?\nಎನ್ನುವುದೇ ನಮಗೆ ಗೊತ್ತಿಲ್ಲ. ಭಗವಂತ ಹಾಗೂ ಜೀವಸ್ವರೂಪ ಎಂದೂ ಬದಲಾಗದಿದ್ದರೂ ಕೂಡಾ, ಅದು\nನಮ್ಮ ಚಿಂತನೆಗೆ ಎಟುಕುವುದಿಲ್ಲ. ಈ ಕಟು ಸತ್ಯವನ್ನು ತಿಳಿದ ಮೇಲೆ ಜೀವ ನಾಶವಾಗುತ್ತದೆ ಎಂದು ದುಃಖಿಸುವ\nಅಗತ್ಯವಿಲ್ಲ.",
  "2.26": "ಅಥ ಚ ಏನಮ್‌ ನಿತ್ಯಜಾತಮ್‌ ನಿತ್ಯಮ್‌ ವಾ ಮನ್ಯಸೇ ಮೃತಮ್‌ |\n\nತದಾ ಅಪಿ ತ್ವಮ್‌ ಮಹಾಬಾಹೋ ನ ಏನಮ್‌ ಶೋಚಿತುಮ್‌ ಅರ್ಹಸಿ -- ಆದರೂ ಈ ಜೀವ ದೇಹದ ಮೂಲಕ\nಸದಾ ಹುಟ್ಟುವವನು ಮತ್ತು ಸಾಯುವವನು ಎಂದು ಭಾವಿಸುವೆಯಾ? ಹಾಗಿದ್ದರೂ, ಓ ಮಹಾವೀರಾ, ನೀನು\nಇವನಿಗಾಗಿ ಕೊರಗುವುದು ತರವಲ್ಲ.\n\nವೇದಾಂತ ಬಿಟ್ಟು ಲೋಕದ ದೃಷ್ಟಿಯಲ್ಲಿ ವಿಚಾರ ಮಾಡಿದರೆ, ಆತ್ಮ ದೇಹದ ಮೂಲಕ ವ್ಯಕ್ತವಾಗುತ್ತದೆ ಹಾಗೂ\nಸಾವಿನ ಮೂಲಕ ಅವ್ಯಕ್ತವಾಗುತ್ತದೆ. ಹುಟ್ಟು-ಸಾವನ್ನು ಮೀರಿ ನಿಲ್ಲುವುದು ಎಂದೂ ಸಾಧ್ಯವಿಲ್ಲ. ಆದ್ದರಿಂದ\nಸಾವಿನ ಬಗ್ಗೆ ದುಃಖ ಪಡುವ ಅಗತ್ಯವಿಲ್ಲ. “ಮಹಾ ಬಲಿಷ್ಠನಾದ ನೀನು ಈ ಹಿಂದೆ ಅದೆಷ್ಟು ಯುದ್ಧಗಳನ್ನು\nಮಾಡಿದ್ದಿ? ಆಗ ಇರದ ಸಮಸ್ಯೆ ಈಗೇಕೆ? ನೀನು ಮಾಡುತ್ತಿರುವುದು ನಿನ್ನ ಕರ್ತವ್ಯವನ್ನೇ ಹೊರತು ಇನ್ನೇನನ್ನೂ\nಅಲ್ಲ”-ಎಂದು ಕೃಷ್ಣ ಅರ್ಜುನನಿಗೆ ತಿಳಿಸಿ ಹೇಳುತ್ತಾನೆ.",
  "2.27": "ಜಾತಸ್ಯ ಹಿ ಧ್ರುವಃ ಮೃತ್ಯುಃ ಧ್ರುವಂ ಜನ್ಮ ಮೃತಸ್ಯ ಚ।\nತಸ್ಮಾತ್‌ ಅಪರಿಹಾರ್ಯೇ ಅರ್ಥೇ ನ ತ್ವಂ ಶೋಚಿತುಮ್‌ ಅರ್ಹಸಿ-- ಹುಟ್ಟಿದವನಿಗೆ ಸಾವು ಖಚಿತ; ಸತ್ತವನಿಗೆ\nಮರುಹುಟ್ಟೂ ಖಚಿತ. ಎಂದ ಮೇಲೆ, ಅನಿವಾರ್ಯವಾದ ಸಂಗತಿಗಾಗಿ ನೀನು ಅಳುವುದು ತರವಲ್ಲ.\n\nಹುಟ್ಟು-ಸಾವು, ಸುಖ-ದುಃಖ, ಒಂದು ನಾಣ್ಯದ ಎರಡು ಮುಖವಿದ್ದಂತೆ. ರಾತ್ರಿ ಇಲ್ಲದೆ ಹಗಲಿಲ್ಲ. ಹುಟ್ಟಿ ದ ಮೇಲೆ\nಸಾವು ಕಟ್ಟಿಟ್ಟ ಬುತ್ತಿ. ನಾವು ಜೀವನದಲ್ಲಿ ಅನಿವಾರ್ಯವಾದದ್ದನ್ನು ಹೊಂದಿಸಿಕೊಳ್ಳುವುದನ್ನು ಕಲಿಯಬೇಕು.\nಅದನ್ನು ಬಿಟ್ಟು ಕಷ್ಟ ಬಂದಾಗ ಕೊರಗುವುದು ತರವಲ್ಲ. ಅನಿವಾರ್ಯವಾದ ಕರ್ತವ್ಯ ಪಾಲನೆಯಲ್ಲಿ ನಾವು\nಎಂದೂ ದುಃಖಿಸಬಾರದು.",
  "2.28": "ಅವ್ಯಕ್ತ ಆದೀನಿ ಭೂತಾನಿ ವ್ಯಕ್ತ ಮಧ್ಯಾನಿ ಭಾರತ |\nಅವ್ಯಕ್ತ ನಿಧನಾನಿ ಏವ ತತ್ರ ಕಾ ಪರಿದೇವನಾ -- ಭರತವಂಶದ ಕುಡಿಯೇ, ಜೀವಿಗಳ ಬದುಕಿನ ಬುಡದ ಬೇರು\nಕಾಣಿಸದು. ನಡು ಮಾತ್ರ ಕಾಣಿಸುತ್ತಿದೆ. ತುದಿಯೂ ಕಾಣಿಸದು. ಹೀಗಿರುವಾಗ ಏಕೆ ಗೋಳಾಡುವುದು?\n\nಇಲ್ಲಿಯವರೆಗೆ ಜೀವ, ಜೀವದ ಇರುವು, ಹುಟ್ಟು ಸಾವಿನ ಬಗ್ಗೆ ಅನೇಕ ರೀತಿಯಲ್ಲಿ ವಿಶ್ಲೇಷಣೆಯನ್ನು ಕೃಷ್ಣನ\nಮಾತಿನಲ್ಲಿ ನೋಡಿದ್ದೇವೆ. ಆದರೆ ಮೂಲಭೂತವಾಗಿ ಅರ್ಜುನನಿಗೆ ಕಾಡಿದ ಸಮಸ್ಯೆ 'ನನ್ನ ಗುರು, ನನ್ನ ಅಜ್ಜ'\nಎನ್ನುವ ಸಂಬಂಧದ ಸೆಳೆತ. ಅಂತಹ ಮಹಾ ಜ್ಞಾನಿಗಳ ವಿರುದ್ಧ ನಿರ್ಲಿಪ್ತನಾಗಿ ಯುದ್ಧ ಮಾಡುವುದು ಹೇಗೆ\nಎನ್ನುವುದು ಆತನ ಸಮಸ್ಯೆ. ಇಲ್ಲಿ ಕೃಷ್ಣ ಆತನ ಸಮಸ್ಯೆಗೆ ಉತ್ತರಿಸುತ್ತಾನೆ.\n\nಒಬ್ಬ ವ್ಯಕ್ತಿ ನಮಗೆ ಸಂಬಂಧಿಯಾಗುವುದು ಆತನ ಹುಟ್ಟಿನ ನಂತರ, ಆದರೆ ಹುಟ್ಟಿನ ಮೊದಲು ಆತ ಏನಾಗಿದ್ದ?\nಸತ್ತ ನಂತರ ಎಲ್ಲಿ ಹೋಗುತ್ತಾನೆ? ಈ ಹುಟ್ಟು-ಸಾವಿನ ಹಿಂದೆ ಮತ್ತು ಮುಂದೆ ನಮಗೂ ಆ ಜೀವಕ್ಕೂ ಏನೂ\nಸಂಬಂಧವಿಲ್ಲ. ಈ ಸಂಬಂಧ ಜೀವದ ನಿರಂತರ ಬದುಕಿನ ಸರಳ ರೇಖೆಯಲ್ಲಿನ ಒಂದು ಬಿಂದು. ಅದು ಮಾತ್ರ\nನಮಗೆ ವ್ಯಕ್ತ. ಉಳಿದದ್ದು ಅವ್ಯಕ್ತ. ಆದ್ದರಿಂದ ಸರಳ ರೇಖೆಯ ಒಂದು ಬಿಂದುವಿನಲ್ಲಿ ನಿಂತು ದುಃಖಿಸುವುದು\n\nಸೂಕ್ತವಲ್ಲ.\n\nಇಲ್ಲಿ ನಾವು ಬದುಕಿದ್ದಾಗ ಒಬ್ಬರನೊಬ್ಬರು ಪ್ರೀತಿಸಬಾರದು ಎಂದಲ್ಲ. ಇದ್ದಾಗ ಪ್ರೀತಿಸು, ಆದರೆ ಇಲ್ಲವಾದಾಗ\nಭಗವಂತ ಕರೆಸಿಕೊಂಡ ಎಂದು ನಿಶ್ಚಿಂತೆಯಿಂದ ಇರಲು ಮನಸ್ಸಿಗೆ ತರೆಬೇತಿ ಕೊಡು. ಈ ರೀತಿ ಬದುಕಲು\nಕಲಿಯದಿದ್ದರೆ ಜೀವನ ದುಸ್ತರವಾಗುತ್ತದೆ. ಇದ್ದಾಗ ಸಂತೋಷದಿಂದಿರು, ಇಲ್ಲದಿದ್ದಾಗ ದುಃಖಿಸಬೇಡ ಎನ್ನುವುದು\nಕೃಷ್ಣನ ಸಂದೇಶ.\n",
  "2.29": "ಆಶ್ಚರ್ಯವತ್‌ ಪಶ್ಯತಿ ಕಶ್ಚಿತ್‌ ಏನಮ್‌ ಆಶ್ಚರ್ಯವತ್‌ ವದತಿ ತಥಾ ಏವ ಚ ಅನ್ಯಃ |\n\nಆಶ್ಚರ್ಯವತ್‌ ಚ ಏನಮ್‌ ಅನ್ಯಃ ಶೃಣೋತಿ ಶ್ರುತ್ವಾ ಅಪಿ ಏನಮ್‌ ವೇದ ನ ಚ ಏವ ಶಶ್ಚಿತ್‌ -- ಯಾರಾದರೂ ಈ\nಜೀವತತ್ವವನ್ನು ಅಥವಾ ಭಗವಂತನನ್ನು ಕಂಡುಕೊಂಡರೆ ಅದೊಂದು ಅಚ್ಚರಿಯಂತೆ. ಇನ್ನೊಬ್ಬ ಅಂದು\nತೋರಿಸಿದರೆ... ಅದೊಂದು. ಅಚ್ಚರಿಯಂತೆ... ಮಗದೊಬ್ಬ ಅದನ್ನು ಕೇಳಿ ತಿಳಿದರೆ. ಅದೂ\nಒಂದಚ್ಚರಿಯಂತೆ.(ಯಾರೋ ಒಬ್ಬ ಭಗವಂತನನ್ನು ಅಚ್ಚರಿಗೊಂಡು ನೋಡುತ್ತಾನೆ. ಯಾರೋ ಒಬ್ಬ\nಅಚ್ಚರಿಗೊಂಡು ಆಡುತ್ತಾನೆ. ಯಾರೋ ಒಬ್ಬ ಅವನನ್ನು ಅಚ್ಚರಿಗೊಂಡು ಕೇಳುತ್ತಾನೆ] ಎಷ್ಟು ಕೇಳಿದರೂ\nಜೀವವನ್ನಾಗಲೀ, ಭಗವಂತನನ್ನಾಗಲೀ ಸರಿಯಾಗಿ ಅರಿತವನು ಯಾರೂ ಇಲ್ಲ.\n\nಇದು ಜೀವ ಹಾಗೂ ಭಗವಂತನ ಬಗ್ಗೆ ಇರುವ ಶ್ಲೋಕ. ಭಗವಂತನನ್ನು ಕಂಡವರು ವಿರಳ. ಒಂದು ವೇಳೆ ಬಹಳ\nಸಾಧನೆಯಿಂದ ಆತನನ್ನು ಕಂಡುಕೊಂಡರೆ, ಕಂಡವರ ಉದ್ಗಾರ ಕೇವಲ ಅಚ್ಚರಿ. ಅದೊಂದು ವಿಸ್ಮಯ. ಈ\nವಿಶ್ವವೇ ಒಂದು ಅದ್ಭುತ, ಹಾಗಿರುವಾಗ ವಿಶ್ವವನ್ನು ನಿರ್ಮಿಸಿದ ಆ ಭಗವಂತ ಅದೆಷ್ಟು ಅದ್ಭುತವಿರಬಹುದು?\nಆದ್ದರಿಂದ ಆತನನ್ನು ಕಂಡವರು ಆತನ ಬಗ್ಗೆ ವರ್ಣಿಸಲಾರರು. ಒಂದು ವೇಳೆ ವರ್ಣಿಸಿದರೆ ಕೇಳುವವನಿಗೆ\nಅದೊಂದು ಅಚ್ಚರಿ. ಯಾರು ಎಷ್ಟೇ ಕೇಳಲಿ ಕೊನೆಗೆ ಭಗವಂತ ಕೇವಲ ಅಚ್ಚರಿಯಾಗೇ ಉಳಿಯುತ್ತಾನೆ.\nಏಕೆಂದರೆ ಭಗವಂತನನ್ನು ತಿಳಿಯುವುದು ಅಸಾಧ್ಯ.\n\nಇದೇ ರೀತಿ ಜೀವ. ಆತ್ಮ ಸಾಕ್ಷಾತ್ಕಾರ ಆದಾಗ ನಮಗಾಗುವುದು ಕೇವಲ ವಿಸ್ಮಯ. ಅದನ್ನು ವರ್ಣಿಸುವುದು\nಅಸಾಧ್ಯ. ಜೀವ ಒಂದು ಬೆಳಕಿನ ಪುಂಜ. ಅದೊಂದು ಮಹಾನ್‌ ಅಚ್ಚರಿ. ಅದು ಸೂರ್ಯನಿಗಿಂತ ಪ್ರಖರ,\nಚಂದ್ರನಿಗಿಂತ ತಂಪಾದ ಬೆಳಕು. ಜೀವತತ್ವದ ಬಗ್ಗೆ ಕೇಳಿ ಅದರ ಬಗ್ಗೆ ಖಚಿತವಾದ ತೀರ್ಮಾನಕ್ಕೆ ಬರುವುದು\n\nಅಸಾಧ್ಯ.",
  "2.30": "ದೇಹೀ ನಿತ್ಯಮ್‌ ಅವಧ್ಯಃ ಅಯಮ್‌ ದೇಹೇ ಸರ್ವಸ್ಯ ಭಾರತ ।\n\nತಸ್ಮಾತ್‌ ಸರ್ವಾಣಿ ಭೂತಾನಿ ನ ತ್ವಮ್‌ ಶೋಚಿತುಮ್‌ ಅರ್ಹಸಿ -- ಓ ಭಾರತಾ, ಎಲ್ಲರ ದೇಹದಲ್ಲೂ ಇರುವ ಈ\nಜೀವ ಎಂದೂ ಕೊಲ್ಲಲಾಗದ್ದು.[ಈ ಜೀವವನ್ನು ಕೊಲ್ಲುವುದು ಎಂದೂ ಸಾಧ್ಯವಿಲ್ಲ. ಏಕೆಂದರೆ ಎಲ್ಲರ ದೇಹದಲ್ಲೂ\nಭಗವಂತ ಜೀವಕ್ಕೆ ಕಾವಲಿದ್ದಾನೆ] ಆದ್ದರಿಂದ ಎಲ್ಲಾ ಜೀವಿಗಳಿಗಾಗಿ ನೀನು ಅಳುವುದು ತರವಲ್ಲ.\n\nಮೂಲಭೂತವಾಗಿ ಯಾರ ದೇಹದಲ್ಲಿರುವ ಜೀವವನ್ನೂ ಸಾಯಿಸುವುದು ಸಾಧ್ಯವಿಲ್ಲ. ದೇಹ ಸಾಯಬೇಕು\nಎನ್ನುವುದು ವಿಧಿ ನಿಯಮ, ಹಾಗೂ ಅದಕ್ಕಾಗಿ ದುಃಖಪಡಬೇಕಾಗಿಲ್ಲ. ತನ್ನ ಸ್ವಂತ ಇಚ್ಛೆಯಿಂದ ದೇಹ ತ್ಯಜಿಸಲು\nಸಾಧ್ಯವಿಲ್ಲ, ಹಾಗೂ ತ್ಯಜಿಸದೇ ಇರಲೂ ಸಾಧ್ಯವಿಲ್ಲ. \"ಅಯಮ್‌ ದೇಹೇ ಸರ್ವಸ್ಯ ಭಾರತ” - \"ರಕ್ಷಣೆ ಮಾಡುವ\n\nಭಗವಂತ ಒಳಗೆ ಕುಳಿತಿರುವಾಗ ಹುಟ್ಟು ಸಾವಿಗೆ ನೀನು ಹೊಣೆಗಾರನಾಗಲಾರೆ. ಭರತವಂಶದಲ್ಲಿ ಹುಟ್ಟಿ ಬಂದ\nನೀನು ಈ ಸತ್ಯವನ್ನು ಅರಿತುಕೋ\" ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಜೀವವೆಂಬ ಬೆಳಕಿನ ಕಿಡಿಯನ್ನು ತಿಳಿದಾಗ, ಅದರ\nಅರಿವು ಬಂದಾಗ-ಹುಟ್ಟು ಸಾವಿನ ಮರ್ಮ ತಿಳಿಯುತ್ತದೆ. ಆಗ ಸಾವು ಒಂದು ಆನಂದದ ಅನುಭವವಾಗುತ್ತದೆ.\nಕೃಷ್ಣನ ಈ ಎಲ್ಲಾ ವಿಶ್ಲೇಷಣೆಯನ್ನು ಕೇಳಿದಾಗ ನಮ್ಮಲ್ಲಿ ಒಂದು ಅಭಿಪ್ರಾಯ ಮೂಡಬಹುದು . \"ಕೊಲ್ಲುವುದು\nತಪ್ಪಲ್ಲ, ಏಕೆಂದರೆ ಜೀವಕ್ಕೆ ಸಾವಿಲ್ಲ. ಎಲ್ಲವೂ ದೈವೇಚ್ಛೆ. ಯಾರು ಯಾರನ್ನು ಬೇಕಾದರೂ ಕೊಲ್ಲಬಹುದು\"\nಎಂದು. ಆದರೆ ಅದು ಸರಿಯಲ್ಲ. ಏಕೆಂದರೆ ಈವರೆಗೆ ನಾವು ನೋಡಿದ ವಿಷಯ ಕೇವಲ ಬದುಕಿನ ಒಳನೋಟ.\nಸಮಾಜ ಜೀವಿಗಳಾದ ನಾವು ಒಳಗಿನ ಅರಿವನ್ನು ಸಮಾಜದ ವಿರುದ್ಧ ಬಳಸುವುದು ಅಧರ್ಮ. ಶಾಸ್ತ್ರಕ್ಕೆ\nಅನುಗುಣವಾಗಿರುವ ಸಮಾಜ ಧರ್ಮವನ್ನು ಪ್ರತಿಯೊಬ್ಬರೂ ಪಾಲಿಸಲೇಬೇಕು. ಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ಕೃಷ್ಣ ಈ\nವಿಚಾರವನ್ನು ಅರ್ಜುನನ ಮುಖೇನ ನಮಗೆ ಸ್ಪಷ್ಟಪಡಿಸುತ್ತಾನೆ.",
  "2.31": "ಸ್ವಧರ್ಮಮ್‌ ಅಪಿ ಚ ಅವೇಕ್ಷ್ಯ ನ ವಿಕಂಪಿತುಮ್‌ ಅರ್ಹಸಿ |\nಧರ್ಮ್ಯಾತ್‌ ಹಿ ಯುದ್ಧಾತ್‌ ಶ್ರೇಯಃ ಅನ್ಯತ್‌ ಕ್ಷತ್ರಿಯಸ್ಯ ನ ವಿದ್ಯತೇ -- ನಿನ್ನ ಧರ್ಮವನ್ನು ಕಂಡಾದರೂ ನೀನು\nಎದೆಗೆಡಬಾರದು ಕ್ಷತ್ರಿಯನಾದವನಿಗೆ ನ್ಯಾಯದಿಂದ ಒದಗಿ ಬಂದ ಕಾಳಗಕ್ಕಿಂತ ಮಿಗಿಲಾದ ಏಳಿಗೆಯಿಲ್ಲ.\n\nಇಲ್ಲಿ ಅರ್ಜುನನ ಸನಾತನ ಧರ್ಮ ಯಾವುದು? ಸಮಾಜ ಧರ್ಮ ಯಾವುದು? ಹಾಗೂ ಸ್ವಧರ್ಮ ಯಾವುದು?\nಸನಾತನ ಧರ್ಮ ಹೇಳುತ್ತದೆ: 'ಅನ್ಯಾಯದ ವಿರುದ್ಧ ಹೋರಾಡಲೇ ಬೇಕು' ಎಂದು; ಸಮಾಜ ಧರ್ಮ\nಹೇಳುತ್ತದೆ: ಕ್ಷತ್ರಿಯನಾದವನು ಅಧರ್ಮದ ವಿರುದ್ಧ ಹೋರಾಡಬೇಕು, ಸಮಾಜದ ರಕ್ಷಣೆ ಮಾಡಬೇಕು ಹಾಗೂ\nಈ ಪುಣ್ಯ ಕಾರ್ಯದಲ್ಲಿ 'ತನ್ನವರು' ಎಂದು ನೋಡಬಾರದು ಎಂದು. ಇನ್ನು ಅರ್ಜುನ ಮೂಲತಃ\nಕ್ಷತ್ರಿಯನಾದ್ದರಿಂದ ಆತನ ಸ್ವಧರ್ಮ 'ಅನ್ಯಾಯದ ವಿರುದ್ಧ ಹೋರಾಟ”. ಇಲ್ಲಿ ವ್ಯಕ್ತಿಧರ್ಮ, ಸಮಾಜಧರ್ಮ\nಹಾಗೂ ಸನಾತನಧರ್ಮ ಏಕವಾಗಿದೆ. ಆದ್ದರಿಂದ ಅನ್ಯಾಯದ ವಿರುದ್ಧ ಹೋರಾಡುವುದು ಮಹಾ ಪುಣ್ಯದ\nಕೆಲಸ. ಸಮಾಜ ಸುರಕ್ಷತೆಗಾಗಿ ಹೋರಾಡುವುದು ಕ್ಷತ್ರಿಯನ ಮಹಾತಪಸ್ಸು. ಇದಕ್ಕಿಂತ ಪುಣ್ಯಕಾರ್ಯ\nಇನ್ನೊಂದಿಲ್ಲ.",
  "2.32": "ಯದೃಚ್ಛಯಾ ಚ ಉಪಪನ್ನಮ್ ಸ್ವರ್ಗ ದ್ವಾರಮ್ ಅಪಾವೃತಮ್ ।\nಸುಖಿನಃ ಕ್ಷತ್ರಿಯಾಃ ಪಾರ್ಥ ಲಭಂತೇ ಯುದ್ಧಮ್ ಈದೃಶಮ್ -- ಯಾವ ಪ್ರಯತ್ನವೂ ಇಲ್ಲದೆ ಒದಗಿ ಬಂದ, ಎದುರಿಲ್ಲದ ಸ್ವರ್ಗದ ಬಾಗಿಲು. ಅದೃಷ್ಟವಂತರು ಕ್ಷತ್ರಿಯರು ಇಂಥ ಕಾಳಗ ಪಡೆಯುತ್ತಾರೆ, ಪಾರ್ಥಾ.\n\nಕಾಲು ಕೆದಕಿ ಯುದ್ಧ ಮಾಡುವುದು ತಪ್ಪು. ಆದರೆ ಇಲ್ಲಿ ಸಮಷ್ಟಿಯಾಗಿ ಬಂದ ಯುದ್ಧದ ಹೊಣೆಗಾರಿಕೆ ಪಾಂಡವರದ್ದಲ್ಲ. ತನ್ನಷ್ಟಕ್ಕೇ ಬಂದು ಎರಗಿದ ಈ ಯುದ್ಧ ದೈವೇಚ್ಛೆ. ಈಶ್ವರನ ಇಚ್ಛೆಯಂತೆ ಎಲ್ಲವೂ ಆಗುವಾಗ, ಏನು ಬಂತೋ ಅದನ್ನು ಹಾಗೇ ಸ್ವೀಕರಿಸಬೇಕು. ಅನ್ಯಾಯದ ವಿರುದ್ಧ ಧರ್ಮಯುದ್ಧ ಮಾಡಿದವನಿಗೆ ಸ್ವರ್ಗದ ಬಾಗಿಲು ಸದಾ ತೆರೆದಿರುತ್ತದೆ. ಇಂತಹ ಯುದ್ಧದ ಅವಕಾಶ ಒಬ್ಬ ಕ್ಷತ್ರಿಯನಿಗೆ ಬರಬೇಕಾದರೆ ಆತ ಪುಣ್ಯ ಮಾಡಿರಬೇಕು. ಇಂತಹ ಸಮಯದಲ್ಲಿ ಕ್ಷತ್ರಿಯನಾದವನು ಕಣ್ಣುಚ್ಚಿ ಕುಳಿತುಕೊಳ್ಳುವುದು ಮಹಾಪಾಪ.\nಇಲ್ಲಿ ನಮಗೆ ಕೃಷ್ಣ ಅರ್ಜುನನಲ್ಲಿ ಯುದ್ಧಮಾಡು ಎಂದು ಏಕೆ ಹೇಳುತ್ತಿದ್ದಾನೆ ಎನ್ನುವುದು ಸ್ಪಷ್ಟವಾಗಿ ತಿಳಿಯುತ್ತದೆ. ಪ್ರತಿಯೊಬ್ಬ ಮಾನವನೂ ಸನಾತನಧರ್ಮ, ಅದಕ್ಕನುಗುಣವಾಗಿ ಸಮಾಜಧರ್ಮ ಹಾಗೂ ಸಮಾಜ ಮತ್ತು ಸನಾತನ ಧರ್ಮಕ್ಕನುಗುಣವಾಗಿ ಸ್ವಧರ್ಮ-ಈ ನೆಲೆಯಲ್ಲಿ ತನ್ನ ಕರ್ತವ್ಯ ನಿರ್ವಹಿಸಬೇಕು. ಈ ನೆಲೆಯಲ್ಲಿ ಮಾಡಿದ ಯಾವ ಕಾರ್ಯವೂ ಪಾಪ ಕಾರ್ಯವಾಗದು. ಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ಈ ಬಗ್ಗೆ ಇನ್ನೂ ಹೆಚ್ಚಿನ ವಿವರವನ್ನು ಕೃಷ್ಣ ಕೊಡುತ್ತಾನೆ. ಸನಾತನಧರ್ಮ, ಸಮಾಜಧರ್ಮ ಮತ್ತು ಸ್ವಧರ್ಮ ಅಂದರೆ ಏನು ಎನ್ನುವದನ್ನು ಈಗಾಗಲೇ ಅಧ್ಯಾಯ ಒಂದರಲ್ಲಿ (ಶ್ಲೋಕ-೪೦) ವಿವರವಾಗಿ ವಿಶ್ಲೇಷಿಸಲಾಗಿದೆ.",
  "2.33": "ಅಥ ಚೇತ್‌ ತ್ವಮ್‌ ಧರ್ಮ್ಯಮ್‌ ಇಮಮ್‌ ಸಂಗ್ರಾಮಮ್‌ ನ ಕರಿಷ್ಯಸಿ |\n\nತತಃ ಸ್ವಧರ್ಮಮ್‌ ಕೀರ್ತಿಮ್‌ ಚ ಹಿತ್ವಾ ಪಾಪಮ್‌ ಅವಾಪ್ಸ್ಯಸಿ - ಒಂದೊಮ್ಮೆ, ನ್ಯಾಯದಿಂದ ಒದಗಿ ಬಂದ\nಈ ಕಾಳಗವನ್ನು ನೀನು ಕೈಗೊಳ್ಳದಿದ್ದರೆ, ಆಗ , ನಿನ್ನ ಧರ್ಮವನ್ನೂ ಹೆಸರನ್ನೂ ಕಳೆದುಕೊಂಡು ಪಾಪವನ್ನು\nಗಳಿಸುವೆ.\n\nಮುಂದುವರಿದು ಕೃಷ್ಣ ಅರ್ಜುನನಲ್ಲಿ ಹೇಳುತ್ತಾನೆ: \"ನೀನು ಪಾಪದ ಭಯದಿಂದ ಯುದ್ಧ ಬೇಡ ಎಂದು\nಹೇಳುತ್ತಿರುವೆ. ಆದರೆ ಯುದ್ಧ ಮಾಡಿದರೆ ಮಾತ್ರ ಧರ್ಮ ಉಳಿಯುತ್ತದೆ, ಹಾಗೂ ನಿನಗೆ ಸ್ವರ್ಗದ ಬಾಗಿಲು\nತೆರೆಯುತ್ತದೆ. ಇಲ್ಲದೆ ಇದ್ದಲ್ಲಿ ನರಕದ ಬಾಗಿಲು ನಿನ್ನನ್ನು ಸ್ವಾಗತಿಸಲಿದೆ” ಎಂದು.\n\nಇಲ್ಲಿ ನೆಡೆಯುತ್ತಿರುವುದು ಒಂದು ಧರ್ಮ ಸಂಗ್ರಾಮ. ಅರ್ಜುನ ಧರ್ಮದ ಪರ ನಿಂತ ಮಹಾರಥಿ. ಆತ ಇಂತಹ\nಧರ್ಮ ಸಂಗ್ರಾಮದಲ್ಲಿ ಧರ್ಮದ ಪರ ಹೋರಾಡದಿದ್ದರೆ ಸಹಜಧರ್ಮಕ್ಕೆ ವಿರುದ್ಧವಾಗಿ ಹಾಗೂ ಸಾಮಾಜಿಕ\nಧರ್ಮವನ್ನು ಬಿಟ್ಟು ನೆಡೆದುಕೊಂಡಂತೆ. ಇದೊಂದು ಕಳಂಕ ಮತ್ತು ಮಹಾ ಪಾಪವಾಗುತ್ತದೆ. ಈ ರೀತಿ ಪಾಪದ\nಭಯದಿಂದ ಬಳಲುತ್ತಿರುವ ಅರ್ಜುನನಿಗೆ ಕೃಷ್ಣ ಯಾವುದು ನಿಜವಾದ ಪಾಪ ಎನ್ನುವುದನ್ನು ಮನವರಿಕೆ\nಮಾಡಿಸುತ್ತಿದ್ದಾನೆ.\n\nಪಾಪ ಕೃತ್ಯ ಯಾವುದು ಎನ್ನುವುದನ್ನು ಸಂದರ್ಭ ನಿರ್ಧರಿಸುತ್ತದೆ. ಉದಾಹರಣೆಗೆ 'ಸತ್ಯ ನುಡಿಯುವುದು\nಪುಣ್ಯದ ಕೆಲಸ' ಎಂದು ಹೇಳಲಾಗದು. ಅದು ಪಾಪವೋ ಪುಣ್ಯವೋ ಎನ್ನುವುದನ್ನು ಸಂದರ್ಭ ನಿರ್ಣಯಿಸುತ್ತದೆ.\nದರೋಡೆಕೋರರಿಂದ ತಪ್ಪಿಸಿಕೊಳ್ಳಲು-ಆಶ್ರಯ ಕೇಳಿ ಬಂದ ವ್ಯಕ್ತಿಯನ್ನು ಅಡಗಿಸಿಟ್ಟು, ದರೋಡೆಕೋರರು\nಬಂದು ಪ್ರಶ್ನಿಸಿದಾಗ ಸತ್ಯ ನುಡಿಯುವುದು ಪಾಪದ ಕೆಲಸ. ಅಡಗಿಸಿಟ್ಟ ವ್ಯಕ್ತಿಯ ರಕ್ಷಣೆಗೋಸ್ಕರ ಸುಳ್ಳನ್ನು\nಹೇಳುವುದು ಪುಣ್ಯದ ಕೆಲಸ. ಇದೇ ರೀತಿ ಇಲ್ಲಿ ಅರ್ಜುನನಿಗೆ ಧರ್ಮದ ರಕ್ಷಣೆಗೋಸ್ಕರ ಗುರು-ಪಿತಾಮಹರನ್ನು\nಎದುರಿಸಿ ಹೋರಾಡುವುದೊಂದೇ ಮಹಾಪುಣ್ಯದ ಕೆಲಸ ಎನ್ನುವುದನ್ನು ಕೃಷ್ಣ ಮನವರಿಕೆ ಮಾಡಿಸುತ್ತಿದ್ದಾನೆ.\n",
  "2.34": "ಅಕೀರ್ತಿಮ್‌ ಚ ಅಪಿ ಭೂತಾನಿ ಕಥಯಿಷ್ಯಂತಿ ತೇ ಅವ್ಯಯಾಮ್‌ |\nಸಂಭಾವಿತಸ್ಯ ಚ ಅಕೀರ್ತಿಃ ಮರಣಾತ್‌ ಅತಿರಿಚ್ಯತೇ--ಜನರು ನಿನ್ನ ಕೊನೆಯಿರದ ಕಳಂಕದ ಕಥೆಯನ್ನು\nಆಡಿಕೊಳ್ಳುತ್ತಾರೆ. ಮರ್ಯಾದೆಯ ಮನುಷ್ಯನಿಗೆ ಕೆಟ್ಟ ಹೆಸರು ಸಾವಿಗಿಂತ ಧಾರುಣ.\n\nಸಾಮಾಜಿಕ ಪರಿಣಾಮದ ಬಗ್ಗೆ ವಿವರಿಸುತ್ತಾ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: ಒಬ್ಬ ಕ್ಷತ್ರಿಯನಿಗೆ ಆತನ ಕೀರ್ತಿ ನಾಶವಾದರೆ\nಆತ ಅವಮಾನಕ್ಕೊಳಗಾಗುತ್ತಾನೆ. ಅದರಿಂದ ಆತ ತನ್ನ ಅಸ್ತಿತ್ವವನ್ನೇ ಕಳೆದುಕೊಳ್ಳಬಹುದು. ಜಗತ್ತಿನಲ್ಲಿ\nಮಹಾನ್‌ ಬಿಲ್ಲೋಜ ಎನ್ನುವ ಕೀರ್ತಿ ಪಡೆದ ಅರ್ಜುನ ಈ ಧರ್ಮಯದ್ಧದಲ್ಲಿ ಪಾಲ್ಗೊಳ್ಳದೇ ಇದ್ದಲ್ಲಿ, ಜನರು\nಅತನನ್ನು ಹೇಡಿ ಎಂದು ಆಡಿಕೊಳ್ಳುತ್ತಾರೆ. ಇತಿಹಾಸದ ಪುಟಗಳಲ್ಲಿ ಆತನ ಹೇಡಿತನ ಮುಂದಿನ ಪೀಳಿಗೆಗೆ ಕೆಟ್ಟ\nಉದಾಹರಣೆಯಾಗಿ ನಿಲ್ಲುತ್ತದೆ. 'ಬಂಧು ಸ್ನೇಹಕ್ಕಾಗಿ ಯುದ್ಧದಿಂದ ಹಿಂದೆ ಸರಿದ. ಎಂದು ಯಾರೂ\nಹೇಳಲಾರರು. ಯುದ್ಧಕ್ಕೆ ಹೆದರಿ ಓಡಿಹೋದ ಹೇಡಿ ಎಂದು ನೀಚವಾಗಿ ಬಯ್ಯುತ್ತಾರೆ. ಒಬ್ಬ ಮರ್ಯಾದಸ್ತ\nಮನುಷ್ಯನಿಗೆ ಅಕೀರ್ತಿ ಎನ್ನುವುದು ಸಾವಿಗಿಂತ ಕೀಳು. ಒಬ್ಬ ಕ್ಷತ್ರಿಯ ಇದನ್ನು ಸಹಿಸಲಾರ.\n",
  "2.35": "ಭಯಾತ್‌ ರಣಾತ್‌ ಉಪರತಮ್‌ ಮಂಸ್ಯಂತೇ ತ್ವಾಮ್‌ ಮಹಾರಥಾಃ |\n\nಯೇಷಾಮ್‌ ಚ ತ್ವಮ್‌ ಬಹುಮತಃ ಭೂತ್ವಾ ಯಾಸ್ಯಸಿ ಲಾಘವಮ್‌--ಯಾರಿಗೆ ನೀನು ಘನತೆಯ\nವ್ಯಕ್ತಿಯಾಗಿದ್ದೆಯೋ ಅಂತಹ ಹಿರಿಯ ತೇರಾಳುಗಳೆದುರು ಹಗುರಾಗುವೆ; ಅವರು ನಿನ್ನನ್ನು ಹೆದರಿ\nಹೋರಾಡಲು ಹಿಂಜರಿದ ಹೇಡಿ ಎಂದು ಭಾವಿಸುತ್ತಾರೆ.\n",
  "2.36": "ಅವಾಚ್ಯ ವಾದಾನ್‌ ಚ ಬಹೂನ್‌ ವದಿಷ್ಯಂತಿ ತವ ಅಹಿತಾಃ |\n\nನಿಂದಂತಃ ತವ ಸಾಮರ್ಥ್ಯಮ್‌ ತತಃ ದುಃಖತರಮ್‌ ನು ಕಿಮ್‌ -ನಿನಗಾಗದವರು ನಿನ್ನ ಕೆಚ್ಚನ್ನು\nಹೀಗಳೆಯುತ್ತಾ, ಬಾಯಿ ತುಂಬಾ ಆಡಬಾರದ ಮಾತುಗಳನ್ನಾಡುತ್ತಾರೆ.. ಅದಕ್ಕೂ ಮಿಗಿಲಾದ ಸಂಕಟ\nಏನುಂಟು ?\n\n\"ಯಾರು ನಿನ್ನನ್ನು ದೊಡ್ಡ ವೀರ ಎಂದು ಕೈ ಮುಗಿದು ತಲೆಬಾಗಿ ನಿಲ್ಲುತ್ತಿದ್ದರೋ, ಅವರು ನಿನ್ನನ್ನು ಹುಲ್ಲಿಗಿಂತ\nಕಡೆಯಾಗಿ. ನೋಡುತ್ತಾರೆ... ಸಮಾಜದಲ್ಲಿ ಉನ್ನತ ಪುರುಷನಾಗಿರುವ ನೀನು. ಅವಮಾನಿತನಾಗಿ\nಬದುಕಬೇಕಾಗುತ್ತದೆ. ಆಡಬಾರದ ಅಸಭ್ಯ ಮಾತುಗಳು ಹುಟ್ಟಿಕೊಳ್ಳುತ್ತವೆ. ಇದರಿಂದ ಈ ಹಿಂದಿನ ಸರ್ವ\nಸಾಧನೆಯೂ ಸುಳ್ಳು ಎಂದು ಹೀಗಳೆದು ಆಡಿಕೊಳ್ಳುತ್ತಾರೆ\".\n\nಒಬ್ಬ 'ಉತ್ತಮ ನ್ಯಾಯಾಧೀಶ ' ಎಂದು ಹೆಸರು ಪಡೆದ ವ್ಯಕ್ತಿ, ಯಾವುದೋ ಒಂದು ಸಂದರ್ಭದಲ್ಲಿ ತನ್ನ\nಆತ್ಮೀಯ ಬಂಧುವಿಗೋಸ್ಕರ ಕೆಟ್ಟ ತೀರ್ಪನ್ನು ಕೊಟ್ಟರೆ, ಆತ ತನ್ನ ಸಂಪೂರ್ಣ ವ್ಯಕ್ತಿತ್ವವನ್ನು\nಕಳೆದುಕೊಳ್ಳುತ್ತಾನೆ. ಆತನ ಹಿಂದಿನ ಎಲ್ಲಾ ಸಾಧನೆಗಳು ಒಂದೇ ಕ್ಷಣದಲ್ಲಿ ಮಣ್ಣುಪಾಲಾಗುತ್ತದೆ. ಆತನಿಂದ\nಶಿಕ್ಷಗೊಳಗಾದ ಅಪರಾಧಿಗಳು ಅಸಭ್ಯವಾಗಿ ಆತನನ್ನು ನಿಂದಿಸುತ್ತಾರೆ. ಇಲ್ಲಿ ಶ್ರೀಕೃಷ್ಣ ಅರ್ಜುನನಿಗೆ ಈ\nಸಾಮಾಜಿಕ ಅರಿವನ್ನು ಕೊಡುತ್ತಿದ್ದಾನೆ.",
  "2.37": "ಹತಃ ವಾ ಪ್ರಾಪ್ಸ್ಯಸಿ ಸ್ವರ್ಗಮ್ ಜಿತ್ವಾ ವಾ ಭೋಕ್ಷ್ಯಸೇ ಮಹೀಮ್ |\nತಸ್ಮಾತ್ ಉತ್ತಿಷ್ಠ ಕೌಂತೇಯ ಯುದ್ಧಾಯ ಕೃತ ನಿಶ್ಚಯಃ -- ಸತ್ತರೆ ಸ್ವರ್ಗ ಸೇರುವೆ. ಗೆದ್ದರೆ ನೆಲವನ್ನಾಳುವೆ. ಆದ್ದರಿಂದ, ಕೌಂತೇಯ, ಹೋರಾಡುವ ತೀರ್ಮಾನ ತಳೆದು ಎದ್ದು ನಿಲ್ಲು.\n\nಯುದ್ಧ ಮಾಡುವುದರಿಂದ ನಾವು ಗೆಲ್ಲುತ್ತೇವೆ ಎನ್ನುವುದು ತಿಳಿಯದು. ಧರ್ಮ ಯುದ್ಧದಲ್ಲಿ ಸತ್ತರೂ ಮೋಕ್ಷ, ಗೆದ್ದರೂ ಮೋಕ್ಷ. ಯಾವುದೋ ಸ್ವಾರ್ಥಕ್ಕಾಗಿ ಮಾಡುತ್ತಿರುವ ಯುದ್ಧವಿದಲ್ಲ. ಅನ್ಯಾಯದ ವಿರುದ್ಧ ಹೋರಾಡುವೆ ಎನ್ನುವ ಸಂಕಲ್ಪದಿಂದ ಎದ್ದು ನಿಂತು ಹೋರಾಡು ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.\n\nನಾವು ಮಾಡುವ ಕಾರ್ಯದಲ್ಲಿ ಧರ್ಮದ ಪರಿಜ್ಞಾನ ಮುಖ್ಯ. ಯಾವುದೇ ಸ್ವಾರ್ಥವಿಲ್ಲದೆ, ಧರ್ಮದ ಮಾರ್ಗವನ್ನು ಅನುಸರಿಸುವವನು ಎಂದೂ ಯಾವುದಕ್ಕೂ ಅಂಜುವ ಅಗತ್ಯವಿಲ್ಲ.",
  "2.38": "ಸುಖ ದುಃಖೇ ಸಮೇ ಕೃತ್ವಾ ಲಾಭ ಅಲಾಭೌ ಜಯ ಅಜಯೌ |\nತತಃ ಯುದ್ಧಾಯ ಯುಜ್ಯಸ್ವ ನ ಏವಮ್‌ ಪಾಪಮ್‌ ಅವಾಪ್ಸ್ಯಸಿ ಸುಖ-ದುಃಖಗಳನ್ನು, ಗಳಿಕೆ-ಇಳಿಕೆಗಳನ್ನು,\nಸೋಲು-ಗೆಲುವನ್ನು ಒಂದೇ ನಿಟ್ಟಿನಿಂದ ಕಂಡು ಮತ್ತೆ ಹೋರಾಡತೊಡಗು. ಆಗ ನಿನಗೆ ಯಾವ ಪಾಪವೂ\nತಟ್ಟದು.\n\nಜೀವನದಲ್ಲಿ ಸುಖ-ದುಃಖ ಎನ್ನು ವುದು ಅನಿವಾರ್ಯ. ಸುಖ-ದುಃಖ, ಗಳಿಕೆ-ಇಳಿಕೆ, ಸೋಲು-ಗೆಲುವು ಎಲ್ಲವನ್ನೂ\nಸಮನಾಗಿ ಕಾಣುವವನಿಗೆ ಯಾವ ಪಾಪವೂ ಅಂಟದು. ಎಲ್ಲವನ್ನು ಸಮದೃಷ್ಟಿಯಿಂದ ಕಾಣುತ್ತಾ, ಕೇವಲ\nಕರ್ತವ್ಯ ಪ್ರಜ್ಞೆಯಿಂದ ಹೋರಾಟ ಮಾಡುವುದು ಬದುಕಿನ ಯಶಸ್ವಿನ ಸೂತ್ರ. ಜಯಿಸಬೇಕು ಎನ್ನುವ\nಸ್ವಾರ್ಥವಿಲ್ಲದೇ; ನಾವೇ ಲಾಭ ಗಳಿಸಬೇಕು-ಅವರು ಮಣ್ಣು ಮುಕ್ಕಲಿ ಎನ್ನು ವ. ದ್ವೇಷವಿಲ್ಲದೇ, ಎಲ್ಲವೂ\nಭಗವಂತನ ಪ್ರಸಾದ ಎನ್ನುವ ಮನೋಭಾವನೆಯಿಂದ ಹೋರಾಡು ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.\n\nಭಗವಂತನ ಈ ನುಡಿಯನ್ನು ಮನುಷ್ಯ ತನ್ನ ಜೀವನದಲ್ಲಿ ಅಳವಡಿಸಿಕೊಂಡರೆ ಆತ ಎಂದೂ ದುಃಖಿ ಆಗಲಾರ.\n\"ಬಂದದ್ದೆಲ್ಲಾ ಬರಲಿ ಗೋವಿಂದನ ದಯೆಯೊಂದಿರಲಿ\"” ಎಂದು ಧರ್ಮ ಮಾರ್ಗದಲ್ಲಿ ಮುನ್ನುಗ್ಗುವವನಿಗೆ ಸದಾ\nಸ್ವರ್ಗದ ಬಾಗಿಲು ತೆರೆದಿರುತ್ತದೆ. ಆತನಿಗೆ ದುಃಖ-ದುಃಖವಾಗಿ ಕಾಣಲಾರದು, ಸೋಲು-ಸೋಲಾಗಿ\nಕಾಣಲಾರದು. ಆತನಿಗೆ ಇಹವೂ-ಸ್ವರ್ಗ ಪರವೂ-ಸ್ವರ್ಗ.\n\nಇಲ್ಲಿಯವರೆಗೆ ಕೃಷ್ಣ ಆತ್ಮತತ್ವದ ಬಗೆಗೆ ಸಾಕಷ್ಟು ವಿವರಣೆಯನ್ನು ಅರ್ಜುನನಿಗೆ ಹೇಳಿದ. ಬದುಕು ಅಂದರೇನು?\nಸಾವು ಅಂದರೇನು? ಆತ್ಮ-ಪರಮಾತ್ಮ, ಆ ತತ್ವಗಳ ಅಂತರಂಗದ ರಹಸ್ಯವೇನು? ಇವು ಹೇಗೆ ಯಾವ\nಬದಲಾವಣೆಯೂ ಇಲ್ಲದೇ ಅನಾದಿನಿತ್ಯ ಎನ್ನುವುದನ್ನು ವಿವರಿಸಿ, ಯುದ್ಧದ ಅವಶ್ಯಕತೆಯನ್ನು ಹೇಳಿದ. ಇಲ್ಲಿಂದ\nಮುಂದೆ ಕೃಷ್ಣ ಸಾಂಖ್ಯದಿಂದ ಕರ್ಮದ ಶಡೆ ತಿರುಗುತ್ತಾನೆ.\n\nನಾವು. ಮನಸ್ಸಿನಲ್ಲಿ ವೇದಾಂತವನ್ನು ಎಷ್ಟು ರೂಢಿಸಿಕೊಂಡರೂ, ತತ್ಕಾಲದ ಮನುಷ್ಯನ ದುಃಖ\nಅದಮ್ಯವಾಗಿರುತ್ತದೆ-ಎನ್ನುವುದನ್ನು ಗೀತೆ ಸ್ಪಷ್ಟವಾಗಿ ತಿಳಿಸುತ್ತದೆ. ಭಗವಂತನಿಂದ ಗೀತೆಯ ಉಪದೇಶವನ್ನು\nಪಡೆದ ಅರ್ಜುನ, ತನ್ನ ಮಗ ಅಭಿಮನ್ಯು ಯುದ್ಧದಲ್ಲಿ ಸತ್ತಾಗ ಪುನಃ ವಿಚಲಿತನಾಗುವುದನ್ನು ನಾವು\nಮಹಾಭಾರತದಲ್ಲಿ ಕಾಣುತ್ತೇವೆ. ಪೂರ್ಣವಾದ ಆತ್ಮಸಾಕ್ಷಾತ್ಕಾರ ಪಡೆಯುವುದು ಅಷ್ಟು ಸುಲಭದ ವಿಷಯವಲ್ಲ.\nಆತ್ಮ ಅಜರ-ಅಮರ ಎಂದು ತಿಳಿದರಷ್ಟೇ ಸಾಲದು, ಪೂರ್ಣವಾಗಿ ತಿಳಿಯಬೇಕು. ಅಂತಹ ಸ್ಥಿತಿಯಲ್ಲಿ ಎಲ್ಲಾ\nದುಃಖವನ್ನು ಮರೆತು ಇರಬಹುದು. ಆದರೆ ಈ ಆತ್ಮ ತತ್ವವನ್ನು ತಿಳಿಯುವ ಬಗೆ ಹೇಗೆ? ಆತ್ಮದ ಜ್ಞಾನವನ್ನು\nಪಡೆಯುವ ಸಾಧನವೇನು? ಕೇಳಿದ ತಕ್ಷಣ ಸಾಕ್ಷಾತ್ಕಾರವಾಗಿ ಮನಸ್ಸಿನಲ್ಲಿ ಗಟ್ಟಿಯಾಗಿ ನಿಲ್ಲುವ ವಿಷಯ ಇದಲ್ಲ.\n\nಅಂದಮೇಲೆ ಮಾನಸಿಕವಾಗಿ ಈ ಉತ್ತುಂಗದ ಸ್ಥಿತಿಯನ್ನು ತಲುಪುವುದು ಹೇಗೆ ಎಂದು ಕೃಷ್ಣ ಮುಂದೆ\nವಿವರಿಸುತ್ತಾನೆ.\n",
  "2.39": "ಏಷಾ ತೇ ಅಭಿಹಿತಾ ಸಾಂಖ್ಯೇ ಬುದ್ಧಿಃ ಯೋಗೇ ತು ಇಮಾಮ್‌ ಶೃಣು |\nಬುದ್ಧ್ವಾ ಯುಕ್ತಃ ಯಯಾ ಪಾರ್ಥ ಕರ್ಮ ಬಂಧಮ್‌ ಪ್ರಹಾಸ್ಯಸಿ -- ಈ ಆತ್ಮ ವಿಜ್ಞಾನದ ತಿಳಿನುಡಿ ನಿನಗೆ\nತಿಳಿಸಿದ್ದಾಯ್ತು, ಅದನ್ನು ಗಳಿಸುವ ಬಗೆಯನ್ನು ಇದೀಗ ಕೇಳು. ಪಾರ್ಥಾ, ಈ ತಿಳಿನುಡಿಯಿಂದ ನೀನು\nತಿಳಿಯಾದಾಗ ಕರ್ಮದ ಕಟ್ಟನ್ನು ಕಳೆದುಕೊಳ್ಳುವೆ.\n\nಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: \" ಇಲ್ಲಿಯವರೆಗೆ ಸಾಂಖ್ಯದ ಬಗ್ಗೆ ಹೇಳಿದ್ದಾಯ್ತು. ಇನ್ನು ಯೋಗದ ಬಗ್ಗೆ ಹೇಳುತ್ತೇನೆ ಕೇಳು”\nಎಂದು. ಇಲ್ಲಿ ಕೃಷ್ಣ ಹೇಳುತ್ತಿರುವ ಸಾಂಖ್ಯಾ - 'ವೈದಿಕ ಸಾಂಖ್ಯ'. ವೈದಿಕ ಸಾಂಖ್ಯವನ್ನು ಪ್ರಚಾರಕ್ಕೆ ತಂದವ\nಕಪಿಲವಾಸುದೇವ. ಸಂಖ್ಯಾ ಅಂದರೆ ಸಮ್ಯಕ್‌ ಖ್ಯಾತಿ ಅಥವಾ ಸರಿಯಾದ ಅರಿವು. ಇದು ಆತ್ಮದ ಅರಿವನ್ನು\nಕೊಡುವ ಮೂಲತತ್ವ. ಈ ಕಾರಣದಿಂದ ಪ್ರಾಚೀನರು ಜ್ಞಾನವನ್ನು ಸಾಂಖ್ಯ ಎಂದು ಕರೆದರು. ಇಲ್ಲಿ ಸಾಂಖ್ಯ\nಎಂದರೆ ಖಚಿತವಾದ ಆತ್ಮ ಜ್ಞಾನ.\n\nಇಲ್ಲಿ ಹೇಳುತ್ತಿರುವ ಯೋಗ ಪತಂಜಲಿಯ ಯೋಗವಲ್ಲ, ವೈದಿಕ ಯೋಗ. ಸಾಮಾನ್ಯ ಯೋಗಕ್ಕೆ ದೇವರ\nಅಸ್ತಿತ್ವದ ಧೃಡ ನಂಬಿಕೆ ಬೇಕಿಲ್ಲ. ಮನಸ್ಸನ್ನು ಯಾವುದೋ ಒಂದರ ಮೇಲೆ ನಿರಂತರ ಏಕಾಗ್ರತೆ\nಮಾಡುವುದರಿಂದ ಅನೇಕ ಪವಾಡಗಳನ್ನು ಮಾಡಬಹುದು. ಆದರೆ ಇದು ನಿಜವಾದ ಆತ್ಮ ಸಾಕ್ಷಾತ್ಕಾರವಲ್ಲ.\nಹತ್ತು ವರ್ಷ ಯೋಗ ಸಾಧನೆ ಮಾಡಿ ನೀರಿನ ಮೇಲೆ ನಡೆಯಲು ಕಲಿತವನ ಕಥೆಯನ್ನು ನಾವೆಲ್ಲರೂ ಕೇಳಿದ್ದೇವೆ.\nಈ ರೀತಿ ಯೋಗದಿಂದ ಪವಾಡಗಳನ್ನು ಕಲಿತು ಪ್ರದರ್ಶಿಸುವುದನ್ನು ವೈದಿಕ ಯೋಗ ನಿಷೇಧಿಸುತ್ತದೆ. ಎಂತಹ\nಅಂತಃಶಕ್ತಿ ಪಡೆದರೂ ಅದನ್ನು ಪ್ರದರ್ಶಿಸಕೂಡಾದು. ನೀರಿನ ಮೇಲೆ ನಡೆಯಲು ಕಲಿತ ತಕ್ಷಣ ನಮಗೆ ಆತ್ಮ\nಸಾಕ್ಷಾತ್ಕಾರವಾಗದು. ಇಂತಹ ಇಂದ್ರಜಾಲವನ್ನು ಯಾರು ಬೇಕಾದರೂ ಗಳಿಸಬಹುದು. ಇಲ್ಲಿ ಕೃಷ್ಣ\nಹೇಳುತ್ತಿರುವುದು ಆತ್ಮ ತತ್ವವನ್ನು ಪಡೆಯುವುದಕ್ಕೆ ಜೀವನದಲ್ಲಿ ಮಾಡಬೇಕಾದ ಸಾಧನೆ ಏನು ಎನ್ನುವ\nವಿಷಯ.\n\nಸಾಂಖ್ಯವನ್ನು ತಿಳಿಯುವ ಮಾತನ್ನು ಹೇಳಿದೆ, ಇನ್ನು ಜ್ಞಾನದ ದಾರಿಯಲ್ಲಿ ಸಾಗಿ ಸಿದ್ಧಿ ಪಡೆಯಬೇಕಾದರೆ\nಬೇಕಾದ ಉಪಾಯವನ್ನು(ಯೋಗವನ್ನು) ಹೇಳುತ್ತೇನೆ ಕೇಳು ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಯಾವ ಅರಿವನ್ನು ಪಡೆದರೆ\nಸಾಧನೆಯ ದಾರಿಯಲ್ಲಿ ಕರ್ಮ ಬಂಧನವನ್ನು ದಾಟಿ ಮುನ್ನೆಡೆಯಬಹುದು ಎನ್ನುವುದನ್ನು ಕೃಷ್ಣ ಮುಂದೆ\nವಿವರಿಸುತ್ತಾನೆ. ಅಧ್ಯಾತ್ಮದ ಸಾಧನೆ ಅಂದರೇನು, ನಮ್ಮ ಜೀವನದಲ್ಲಿ ಅಧ್ಯಾತ್ಮದ ಸಾಧನೆ ಹೇಗಿರಬೇಕು,\nಅದನ್ನು ಸಾಧಿಸುವುದು ಹೇಗೆ ಎನ್ನುವುದು ನಾವು ತಿಳಿಯಬೇಕಾದ ಮುಖ್ಯವಾದ ವಿಷಯ.\n\nಅನೇಕ ಮಂದಿ ಹೊರಗಿನಿಂದ ಹೇಗಿರಬೇಕು ಎಂದು ಅನೇಕ ರೀತಿ ಹೇಳುತ್ತಾರೆ. ಆದರೆ ಒಳಗಿನಿಂದ\nಹೇಗಿರಬೇಕು ಎನ್ನುವುದನ್ನು ಯಾರೂ ಹೇಳುವುದಿಲ್ಲ. ಇಷ್ಟು ಹೊತ್ತು ಜಪ ಮಾಡಬೇಕು, ಈ ರೀತಿ\nಮಡಿಯಾಗಿರಬೇಕು, ಇಷ್ಟು ಮಂತ್ರ ಹೇಳಬೇಕು ಇತ್ಯಾದಿ ವಿಚಾರವನ್ನು ಎಲ್ಲರೂ ಹೇಳುತ್ತಾರೆ. ಆದರೆ\nಅಂತರಂಗ ಹೇಗಿರಬೇಕು ಎನ್ನುವುದು ಹೆಚ್ಚಿನವರಿಗೆ ತಿಳಿದಿಲ್ಲ. ಅಂತರಂಗದ ಸಾಧನೆ ಇಲ್ಲದೆ ಕೇವಲ ಬಾಹ್ಯ\nವೇಷದಿಂದ, ಜಪ-ತಪದಿಂದ, ಎನನ್ನೂ ಸಾಧಿಸಲು ಸಾಧ್ಯವಿಲ್ಲ. ಯೋಗ ಸಾಧನೆ ಎಂದರೆ ನಾವು ಯಾವ ಬಟ್ಟೆ\nತೊಡುತ್ತೇವೆ, ಮೈಗೆ ಏನು ಹಚ್ಚಿಕೊಳ್ಳುತ್ತೇವೆ ಎನ್ನುವುದಲ್ಲ. ಅದು ನಮ್ಮ ಅಂತರಂಗದ ನಡೆ. ಅಂತರಂಗ ಮತ್ತು\nಬಹಿರಂಗ ಏಕವಾಗಿರುವ ಸ್ಥಿತಿ. ನಮ್ಮ ನಡೆ, ನಮ್ಮ ನಂಬಿಕೆ, ನಮ್ಮ ಪ್ರಾಮಾಣಿಕತೆಯೇ ನಮ್ಮ ನಿಜವಾದ\nಧರ್ಮ. ಅಂತಹ ಅಂತರಂಗದ ಸಾಧನೆ ಅತಿ ಮುಖ್ಯ. ಅದನ್ನು ಕೃಷ್ಣ ಮುಂದೆ ವಿವರಿಸುತ್ತಾನೆ.\n\nಜ್ಞಾನ ಬೇಕು ನಿಜ, ಆದರೆ ಆತ್ಮ ಜ್ಞಾನವನ್ನು ಪಡೆಯಲು ನಮ್ಮ ಸಾಧನೆ ಏನಿರಬೇಕು, ಈ ಸಂಸಾರ ಬಂಧವನ್ನು\nಕಳಚಿಕೊಳ್ಳುವ ಸಾಧನೆ ಯಾವುದು, ಎನ್ನುವುದನ್ನು ಮುಂದಿನ ಶ್ಲೋಕಗಳಲ್ಲಿ ಸುವಿವರವಾಗಿ ಕಾಣುತ್ತೇವೆ.",
  "2.40": "ನ ಇಹ ಅಭಿಕ್ರಮ ನಾಶಃ ಅಸ್ತಿ ಪ್ರತ್ಯವಾಯಃ ನ ವಿದ್ಯತೇ |\nಸು ಅಲ್ಬಮ್‌ ಅಪಿ ಅಸ್ಯ ಧರ್ಮಸ್ಯ ತ್ರಾಯತೇ ಮಹತಃ ಭಯಾತ್‌ -- ಇಲ್ಲಿ ತೊದಲು ಹೆಜ್ಜೆ ಕೂಡಾ ಹಾಳಾಗದು.\nಇಲ್ಲಿ ತೊಡರುಗಳಿಲ್ಲ; ಈ ಧರ್ಮದ ತುಣುಕು ಕೂಡಾ ದೊಡ್ಡ ಬೆದರಿನಿಂದ ಪಾರುಮಾಡಬಲ್ಲುದು.\n\nಸಾಧನೆಯ ಬಗ್ಗೆ ಹೇಳುವ ಮೊದಲು ಕೃಷ್ಣ ನಮಗೆ ಬರಬಹುದಾದ ಒಂದು ಸಂಶಯವನ್ನು ಈ ಶ್ಲೋಕದಲ್ಲಿ\nಪರಿಹರಿಸಿದ್ದಾನೆ. ಎಲ್ಲರನ್ನೂ ಒಂದು ಪ್ರಶ್ನೆ ಕಾಡಬಹುದು. ಅದೇನೆಂದರೆ: ಮೊದಲು ಹುಟ್ಟು, ಆನಂತರ\nಅಧ್ಯಯನ, ಸಾಧನೆ, ನಂತರ ಸಾವು. ಪುನಃ ಮರು ಹುಟ್ಟು ಮತ್ತೆ ಅದೇ ಸಾಧನೆ ಮತ್ತೆ ಸಾವು! ಇದರಿಂದ ಏನು\nಉಪಯೋಗ ಎಂದು. ಒಂದು ಜನ್ಮದಲ್ಲಿ ಬ್ರಹ್ಮಸಾಕ್ಷಾತ್ಕಾರವಾಗದೇ ಇದ್ದರೆ ಆ ಎಲ್ಲಾ ಸಾಧನೆ ವ್ಯರ್ಥವೇ?\nಖಂಡಿತವಾಗಿ ಇಲ್ಲ ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ನಮ್ಮ ಜೀವನದಲ್ಲಿ ಗಳಿಸಿದ ಐಹಿಕ ಸಂಪತ್ತು(ಧನ, ಒಡವೆ, ಕೀರ್ತಿ, ಆಸ್ತಿ\nಇತ್ಯಾದಿ) ಸತ್ತ ನಂತರ ನಮ್ಮೊಂದಿಗೆ ಬಾರದು ನಿಜ. ಆದರೆ ಅಧ್ಯಾತ್ಮ ಸಾಧನೆ ಹಾಗಲ್ಲ. ಒಂದು ಜನ್ಮದಲ್ಲಿ\nಮಾಡಿದ ಅಧ್ಯಾತ್ಮ ಸಾಧನೆ ಎಂದೂ ನಾಶವಾಗದು. ಈ ಜನ್ಮದಲ್ಲಿ ಅಧ್ಯಾತ್ಮದ ಒಂದು ಮೆಟ್ಟಿಲನ್ನು ಹತ್ತಿದರೆ\nಮುಂದಿನ ಜನ್ಮದಲ್ಲಿ ಹುಟ್ಟುವಾಗಲೇ ನಾವು ಎರಡನೇ ಮೆಟ್ಟಲಲ್ಲಿರುತ್ತೇವೆ. ಹಿಂದಿನ ಜನ್ಮದಲ್ಲಿ ಎಲ್ಲಿ\nನಿಂತಿದ್ದೇವೋ ಅಲ್ಲಿಂದ ಮುಂದುವರಿಯುವ ಪರಿಸರದಲ್ಲಿ ನಮ್ಮ ಜನನವಾಗುತ್ತದೆ. ಸಾಮಾಜಿಕವಾಗಿ ನೀವು\nಅಸಾಧಾರಣ ಪ್ರತಿಭೆಯುಳ್ಳ ಮಕ್ಕಳು ಜನಿಸುವುದನ್ನು, ಹಾಗೂ ಅತ್ಯಂತ ಕಡಿಮೆ ಸಮಯದಲ್ಲಿ ಮಹಾನ್‌\nಸಾಧನೆ ಮಾಡುವುದನ್ನು ಕಾಣುತ್ತೀರಿ. ಇದು ಅವರು ಹಿಂದಿನ ಜನ್ಮದಿಂದ ಪಡೆದು ಬಂದ ಜ್ಞಾನ. ಹಿಂದಿನ\n\nಜನ್ಮದ ಅಧ್ಯಾತ್ಮದ ಸಾಧನೆಯ ಮುಂದುವರಿದ ಭಾಗವೇ ಈ ಜನ್ಮ. ನಾವು ಆ ಜನ್ಮದಲ್ಲಿ ಎಲ್ಲಿ ನಿಲ್ಲಿಸಿದ್ದೇವೋ\nಅಲ್ಲಿಂದಲೇ ಈ ಜನ್ಮದ ಸಾಧನೆ ಪ್ರಾರಂಭವಾಗಿ ಮುಂದುವರಿಯುತ್ತದೆ.\n\nಒಂದು ವೇಳೆ ನಮಗೆ ಅಧ್ಯಾತ್ಮ ಸಾಧನೆ ಮಾಡಬೇಕು ಎನ್ನುವ ಅಂತರಂಗದ ತುಡಿತವಿದ್ದು, ಅದನ್ನು ಈ\nಜನ್ಮದಲ್ಲಿ ಸಾಧಿಸಲಾಗದಿದ್ದಲ್ಲಿ ಮುಂದಿನ ಜನ್ಮದಲ್ಲಿ ಸಾಧನೆಗೆ ಬೇಕಾದ ವಾತಾವರಣದಲ್ಲಿ, ವಿದ್ವಾಂಸರ\nಸಂಗವಿರುವ ಕಡೆ ನಮ್ಮ ಜನ್ಮವಾಗುತ್ತದೆ. ಆದ್ದರಿಂದ ನಮ್ಮ ಅಧ್ಯಾತ್ಮ ಚಿಂತನೆಯಲ್ಲಿ ನಮ್ಮ ಒಂದೊಂದು ಜನ್ಮ\nಒಂದೊಂದು ತರಗತಿ ಇದ್ದಂತೆ. ಒಂದು ಗ್ರಂಥವನ್ನು ಸಂಪೂರ್ಣ ತಿಳಿಯಲು ನಾವು ಅನೇಕ ಜನ್ಮ ಸಾಧನೆ\nಮಾಡಬೇಕು. ಈ ಕಾರಣದಿಂದ ಅಧ್ಯಾತ್ಮ ಸಾಧನೆ ಎಂದೂ ವ್ಯರ್ಥವಲ್ಲ. ಇಂದು ನೀವು ನಿಮ್ಮ ಜೀವನದ ಯಾವ\nಘಟ್ಟದಲ್ಲಿದ್ದರೂ ಸರಿ, ಅಧ್ಯಾತ್ಮ ಸಾಧನೆಗೆ ಇದು ಸಕಾಲ. ಇಂದೇ ನಿಮ್ಮ ಸಾಧನೆಯನ್ನು ಆರಂಭಿಸಿ. ಅದು\nನಿಮ್ಮನ್ನು ಮೋಕ್ಷ ಮಾರ್ಗದತ್ತ ಕೊಂಡೊಯ್ಯುತ್ತದೆ ಎನ್ನುವುದು ಕಟುಸತ್ಯ. ಅಧ್ಯಾತ್ಮ ಪ್ರದರ್ಶನದ ವಸ್ತುವಲ್ಲ,\nಅದು ಅಂತರಂಗದ ಸಾಧನೆ. ನಮ್ಮ ಜನ್ಮದಲ್ಲಿ ನಾವು ಅಧ್ಯಾತ್ಮದ ಕಿಂಚಿತ್‌ ಸಾಧನೆ ಮಾಡಿದರೂ ಕೂಡಾ,\nಅದು ನಮ್ಮನ್ನು ಭಯದಿಂದ ಪಾರು ಮಾಡುತ್ತದೆ. ಭಯದಿಂದ ಅಭಯದತ್ತ ನಮ್ಮನ್ನು ಸಾಗಿಸುವ ಏಕಮಾತ್ರ\nಸಾಧನ ಅಧ್ಯಾತ್ಮ.\nಸಾಧಕರಲ್ಲಿ ಮೂರು ವಿಧ. ಉತ್ತಮ ಸಾಧಕ, ಮಧ್ಯಮ ಸಾಧಕ, ಅಧಮ ಸಾಧಕ. ಉತ್ತಮ ಸಾಧಕ ದೇವರು\nಒಬ್ಬನೇ ಎಂದು ನಂಬಿರುತ್ತಾನೆ. ಇಂತಹ ಭಕ್ತರನ್ನು ಭಾಗವತರು ಎನ್ನುತ್ತಾರೆ. ಆತನಿಗೆ ಭಗವಂತನಲ್ಲಿ\nಏಕನಿಷ್ಠೆ ಇರುತ್ತದೆ. ಭಗವಂತನನ್ನು ಯಾವ ಶಬ್ದದಿಂದ ಕರೆದರೂ ಅದು ಆ ಆದಿಶಕ್ತಿಯಾದ ಪರಶಕ್ತಿಯನ್ನು\nಹೇಳುತ್ತದೆ ಎನ್ನುವ ಸತ್ಯವನ್ನು ಆತ ತಿಳಿದಿರುತ್ತಾನೆ. ಈತ ನಿಜವಾದ ಸಾಧಕ, ಹಾಗೂ ಇದು ಸಾಧನೆಯ\nನಿಜವಾದ ದಾರಿ. ಇನ್ನು ಮಧ್ಯಮ ಸಾಧಕರು: ಇವರು ಪ್ರತಿಯೊಂದು ದೇವತೆಯನ್ನು ಪರಿ ಪರಿಯಾಗಿ ಪೂಜಿಸಿ\nಕೊನೆಗೆ \"ಕೃಷ್ಣಾರ್ಪಣ ಮಸ್ತು\" ಎಂದು ಭಗವಂತನಿಗೆ ಅರ್ಪಿಸುತ್ತಾರೆ. ಇವರನ್ನು ತ್ರೈವಿಧ್ಯರು ಎನ್ನುತ್ತಾರೆ. ಇನ್ನು\nಅಧಮ ಸಾಧಕ; ಈತ ದೇವರು ನೂರಾರು ಎಂದು ನಂಬಿ ಪೂಜಿಸುತ್ತಿರುತ್ತಾನೆ. ಭಗವಂತ ಸರ್ವಾಂತರ್ಯಾಮಿ\nಎನ್ನುವ ಭಾವನೆ ಈತನಿಗಿರುವುದಿಲ್ಲ. ಈತನಿಗೆ ಅಧ್ಯಾತ್ಮದ ನಿಜವಾದ ಕಲ್ಪನೆ ಇರುವುದಿಲ್ಲ. ಆದ್ದರಿಂದ ಇದು\nನಿಜವಾದ ಅಧ್ಯಾತ್ಮ ಸಾಧನೆ ಆಗದು.\n\nನಾವು ಏಕನಿಷ್ಠೆಯಿಂದ ಮಾಡುವ ಸಾಧನೆ ಎಂದೂ ವ್ಯರ್ಥವಾಗದು. ಇಲ್ಲಿ ತೋರ್ಪಡಿಕೆಯ ಅಗತ್ಯವಿಲ್ಲ. ಆದರೆ\nಪ್ರಾಮಾಣಿಕ ನಿಷ್ಠೆ ಅಗತ್ಯ. ಗಣಪತಿಯನ್ನು ಪೂಜಿಸು, ವಾಯುವನ್ನು ಪೂಜಿಸು, ಸೂರ್ಯನನ್ನು ಪೂಜಿಸು, ಅಲ್ಲಾ\nಎಂದು, ಯೇಸು ಎಂದು, ಶಿವನೆಂದು, ವಿಷ್ಣುವೆಂದು, ಏನೇ ಅಂದು ಪೂಜಿಸಿದರೂ ಕೂಡಾ, ಎಲ್ಲಾ ಶಬ್ದಗಳೂ\nಆದಿಶಕ್ತಿಯಾದ ಪರಶಕ್ತಿ ಎನ್ನುವ ಸತ್ಯ ತಿಳಿದು, ಏಕನಿಷ್ಠೆ ಇಟ್ಟು, ಪರಿಶುದ್ಧ ಪ್ರಾಮಾಣಿಕ ಚಿಂತನೆ ಮಾಡಿದಾಗ\nಅದು ನಿಜವಾದ ಅಧ್ಯಾತ್ಮ ಸಾಧನೆಯಾಗುತ್ತದೆ ಹಾಗೂ ವ್ಯರ್ಥವಾಗದೇ ನಮ್ಮೊಂದಿಗೆ ಬರುತ್ತದೆ. ಇಂತಹ\nಸಾಧನೆಯಲ್ಲಿ ದ್ವೇಷ, ಸ್ವಾರ್ಥ, ಅಹಂಕಾರ, ದುಃಖ ಎಂದೂ ಇರುವುದಿಲ್ಲ. ಎಲ್ಲವೂ ಭಗವಂತನ ಪ್ರಸಾದ ಎನ್ನುವ\nಭಾವನೆ ನಮ್ಮನ್ನು ಎತ್ತರಕ್ಕೆ ಕೊಂಡೊಯ್ಯುತ್ತದೆ.",
  "2.41": "ವ್ಯವಸಾಯ ಆತ್ಮಿಕಾ ಬುದ್ಧಿಃ ಏಕಾ ಇಹ ಕುರುನಂದನ |\n\nಬಹುಶಾಖಾಃ ಹಿ ಅನಂತಾಃ ಚ ಬುದ್ಧಯಃ ಅವ್ಯವಸಾಯಿನಾಮ್‌-ಕುರುಕುಮಾರಾ, ಈ ದಾರಿಯಲ್ಲಿ\nಮನನದಿಂದ ಹದಗೊಂಡ ಮಾತು ಒಂದೇ ತರ. ಹದವಿರದವರ ತುದಿಯಿರದ ಹರಟೆಗಳಿಗೆ ಹತ್ತು ಹಲವು\nಟಿಸಿಲುಗಳು.\n\nಏಕನಿಷ್ಠೆಯಿಂದ ನಾವು ಮಾಡುವ ಸಾಧನೆ ವ್ಯರ್ಥವಲ್ಲ ಎನ್ನುವ ವಿಷಯ ನಮಗೆ ತಿಳಿಯಿತು, ಆದರೆ ಯಾವುದು\nಸರಿ ಹಾಗೂ ಯಾವುದು ತಪ್ಪು ಎನ್ನುವುದನ್ನು ತಿಳಿಯುವ ಬಗೆ ಹೇಗೆ? ಕೃಷ್ಣ ಈ ಶ್ಲೋಕದಲ್ಲಿ ನಮ್ಮ ಪ್ರಶ್ನೆಗೆ\nಉತ್ತರ ಕೊಟ್ಟಿದ್ದಾನೆ.\n\nಎಲ್ಲಾ ಕಾಲದಲ್ಲೂ ನಿರ್ಣಾಯಕವಾದ ಮಾತು ಏಕರೂಪವಾಗಿರುತ್ತದೆ. ನಿರ್ಣಯ ಇಲ್ಲದೆ ಆಡುವ ಮಾತು\nಒಂದೊಂದು ಒಂದೊಂದು ತರಹ. ಗೊತ್ತಿಲ್ಲದೆ ಅಜ್ಞಾನದಿಂದ ಆಡುವ ಮಾತುಗಳಿಗೆ ತಲೆಬುಡವಿಲ್ಲದ ಅನಂತ\nಶಾಖೆ. ಆದರೆ ನಿಜವಾಗಿ ತಿಳಿದವರ ನಿರ್ಣಯಾತ್ಮಕವಾದ ಮಾತು ಸದಾ ಒಂದೇ ಆಗಿರುತ್ತದೆ. ಆದ್ದರಿಂದ\nಸತ್ಯವನ್ನು ಅರಿತವರ ಮಾರ್ಗದರ್ಶನದಂತೆ ನಡೆ ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.\n",
  "2.42": "ಯಾಮ್‌ ಇಮಾಮ್‌ ಪುಷ್ಟಿತಾಮ್‌ ವಾಚಮ್‌ ಪ್ರವದಂತಿ ಅವಿಪಶ್ಚಿತಃ |\nವೇದವಾದರತಾಃ ಪಾರ್ಥನ ಅನ್ಯತ್‌ ಅಸ್ತಿ ಇತಿ ವಾದಿನಃ -- ಓ ಪಾರ್ಥಾ, ಅರೆಬರೆ ತಿಳಿದವರು ಹೇಳುತ್ತಾರೆ: ಈ\nವೇದವಾಣಿ ಸ್ವರ್ಗವೆಂಬ ಹೂಬಿಡುವ ಬಳ್ಳಿ. ಹುಟ್ಟು ಕರ್ಮದ ಕಟ್ಟು ಗಳ ಸಂಸಾರವೇ ಇದರ ಹಣ್ಣು.\n",
  "2.43": "ಕಾಮ ಆತ್ಮಾನಃ ಸ್ವರ್ಗ ಪರಾಃ ಜನ್ಮ ಕರ್ಮ ಫಲ ಪ್ರದಾಮ್‌ |\n\nಕ್ರಿಯಾ ವಿಶೇಷ ಬಹುಲಾಮ್‌ ಭೋಗ ಐಶ್ವರ್ಯ ಗತಿಮ್‌ ಪ್ರತಿ -- ಐಷಾರಾಮದ ಐಸಿರಿಯ ಬದುಕಿಗಾಗಿ ಅದರ\nತುಂಬಾ ಬಗೆ ಬಗೆಯ ಕರ್ಮ ಕಲಾಪಗಳು. ಅವರು ವೇದದ ಹೊರನೋಟದ ಅರ್ಥದಲ್ಲೇ ನಿಂತುಬಿಡುವರು.\n[ವೇದದಲ್ಲಿ ವಿವಾದ ಬೆಳೆಸುವವರು, ಅಥವಾ ಅರ್ಥವನ್ನ ರಿಯದೇ ಬರಿದೆ ಉರು ಹೊಡೆಯುವವರು] ಅದರಾಚೆ\nಏನೂ ಇಲ್ಲ ಎನ್ನುವವರು. ಬಗೆಯಲ್ಲಿ ಆಸೆ ತುಂಬಿ ಸ್ವರ್ಗದ ಕನಸು ಕಾಣುವವರು.\n",
  "2.44": "ಪ್ರಸಕ್ತಾನಾಂ ತಯಾಪಹೃತ ಚೇತಸಾಮ್‌ ।\nವ್ಯವಸಾಯಾತ್ಮಿಕಾ ಬುದ್ಧಿಃ ಸಮಾಧೌ ನ ವಿಧೀಯತೇ-ಭೋಗದಲ್ಲಿ ಸಿಲುಕಿದ, ಅರೆಬರೆ ತಿಳಿವಿನ ತಿಳಿಗೇಡಿಗಳ ಮಾತಿಗೆ ಮಾರುಹೋಗಿ ಬುದ್ಧಿ ಗೆಟ್ಟ ಇಂತವರಿಗೆ, ಹದಗೊಂಡ ತಿಳಿನುಡಿ ಕೂಡಾ ಮನಸ್ಸಿನ ಸಮಸ್ಥಿತಿಗೆ ನೆರವಾಗದು.\n\nಮೇಲಿನ ಮೂರು ಶ್ಲೋಕ ಅತ್ಯಂತ ಮುಖ್ಯವಾದುದು. ಹೆಚ್ಚಿನವರಿಗೆ ಇದು ಅರ್ಥವೇ ಆಗುವುದಿಲ್ಲ. ಅರ್ಥವಾಗದೇ ಈ ಶ್ಲೋಕವನ್ನು ಟೀಕಿಸಿದವರೂ ಇದ್ದಾರೆ! ಪ್ರಾಚೀನ ಗ್ರಂಥಗಳಲ್ಲಿ, ವೇದಗಳಲ್ಲಿ, ಶ್ರುತಿಗಳಲ್ಲಿ, ಕೇವಲ ಅಧ್ಯಾತ್ಮವಲ್ಲದೆ ಅನೇಕ ಲೌಕಿಕ ವಿಷಯಗಳು ತುಂಬಿಕೊಂಡಂತೆ ಕಾಣುತ್ತದೆ. ಬರಿಯ ವೇದ ಗ್ರಂಥಗಳನ್ನು ಓದುವುದರಿಂದ ನನ್ನನ್ನು ತಿಳಿಯಲು ಸಾಧ್ಯವಿಲ್ಲ ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ ವೇದವಾದಿಗಳಾದವರು ವೇದದ ಮೇಲ್ನೋಟದ ಅರ್ಥವೆಂಬ ಹೂವನ್ನು ಕಿತ್ತು ತೆಗೆದುಕೊಂಡು ಆಳವಾದ ಜ್ಞಾನ ಸಾಗರವೆಂಬ ಹಣ್ಣಿನಿಂದ ವಂಚಿತರಾಗುತ್ತಾರೆ ಎಂದು. ವೇದವನ್ನು ಆಳವಾಗಿ ಅರ್ಥ ಮಾಡಿಕೊಳ್ಳದೇ, ಕೇವಲ ಮೇಲ್ನೋಟದ ಅರ್ಥದಲ್ಲೇ ನಿಂತು ವೇದವೆಂದರೆ ಇಷ್ಟೇ ಎಂದು ಹೇಳುವವರಿಗೆ ಕೃಷ್ಣ ಈ ಮಾತನ್ನು ಹೇಳಿದ್ದಾನೆ. ಇಲ್ಲಿ 'ವೇದವಾದರು' ಎಂದರೆ ವೇದದ ಅರ್ಥ ತಿಳಿಯದೇ ಅದರ ಬಗ್ಗೆ ವಿವಾದ ಮಾಡುವವರು. ವೇದವನ್ನು ಬಾಯಿಪಾಠ ಮಾಡಿ ಅದರ ಅರ್ಥ ತಿಳಿಯದೇ ಮಾತನಾಡುವವರು. ವೇದದ ಮೇಲ್ನೊ ಟದ ಅರ್ಥದಲ್ಲೇ ನಿಂತವರು. ಇವರು ಮೇಲಿನಿಂದ ಈಜುವವರು. ಇವರಿಗೆ ತಳದಲ್ಲಿರುವ ಮುತ್ತು ರತ್ನಗಳ ಅರಿವಿಲ್ಲ. ವೇದವನ್ನು ನಿಜವಾಗಿ ಅರಿತುಕೊಳ್ಳದೇ, ಅದರ ಬಗ್ಗೆ ತಪ್ಪು ಕಲ್ಪನೆ ಮಾಡಿಕೊಂಡು, ಅದನ್ನೇ ಜನರಿಗೆ ಹೇಳುವುದು ನರಕಕ್ಕೆ ನೇರ ದಾರಿ. ಪೌರೋಹಿತ್ಯ ಕೂಡಾ ಹೀಗೆ. ನಿಜವಾದ ಜ್ಞಾನವಿಲ್ಲದೆ, ಮಂತ್ರದ ಅರ್ಥ ಗೊತ್ತಿಲ್ಲದೆ ಪೌರೋಹಿತ್ಯ ಮಾಡುವುದು ಕೂಡಾ ಅಷ್ಟೆ ೀ ಅಪಾಯಕಾರಿ. ಪೌರೋಹಿತ್ಯ ಒಂದು ಜವಾಬ್ದಾರಿಯುತ ಕೆಲಸ. ಒಬ್ಬ ಮನುಷ್ಯನ ಪಾಪವನ್ನು ಪರಿಹರಿಸಿ ಅವನನ್ನು ಎತ್ತರಕ್ಕೇರಿಸಬೇಕಾದರೆ ಪೌರೋಹಿತ್ಯ ಮಾಡುವವನೂ ಕೂಡಾ ಎತ್ತರದಲ್ಲಿರಬೇಕು. ವೇದಮಂತ್ರದ ರಹಸ್ಯ ತಿಳಿದವನಾಗಿರಬೇಕು. ಕೃಷ್ಣ ಇಲ್ಲಿ ಹೇಳುತ್ತಾನೆ: “ವೇದದ ಅಂತರಂಗದ ಅರ್ಥ ತಿಳಿಯದಿದ್ದರೆ ಎಲ್ಲವೂ ಅಪಾರ್ಥವಾಗುತ್ತದೆ. ಯಾರು ಪ್ರಾಚೀನ ಗ್ರಂಥಗಳ ಮೇಲ್ನೋಟದ ಅರ್ಥವನ್ನು ಹೇಳಿ ಸಮಾಜಕ್ಕೆ ಮೋಸ ಮಾಡುತ್ತಾರೋ ಅವರು ಅವಿಪಶ್ಚಿತರು” ಎಂದು. 'ವಿಪಶ್ಚಿತರು' ಎಂದರೆ ಜ್ಞಾನ ಸ್ವರೂಪವಾದ ಆತ್ಮವನ್ನು ಕಂಡವರು, ಆತ್ಮ ಜ್ಞಾನಿಗಳು. ಅವಿಪಶ್ಚಿತರು ಶಾಸ್ತ್ರಕ್ಕೆ ಮೇಲ್ನೋಟದ ಅರ್ಥವನ್ನು ಹೇಳುವವರು-ಅವರು ತಿಳಿಗೇಡಿಗಳು ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ! ಈ ಮಾತು ಪ್ರಪಂಚದ ಪ್ರತಿಯೊಂದು ಧರ್ಮ ಗ್ರಂಥಗಳಲ್ಲಿದೆ. ಬೈಬಲ್‌ನಲ್ಲಿ ಇದನ್ನು ಗೂಡಾರ್ಥ ಎನ್ನುತ್ತಾರೆ. ಕುರಾನಿನಲ್ಲಿ ಕೂಡಾ ಈ ಬಗ್ಗೆ ಎಚ್ಚರದ ನುಡಿ ಇದೆ. \"In it are verses that are clear, and others are verses that are ambiguous.\" ಇದು ಕುರಾನ್‌ನಲ್ಲಿ ಬರುವ ಒಂದು ನುಡಿ. ಎಲ್ಲಾ ಪ್ರಾಚೀನ ಅನುಭಾವ ಸಾಹಿತ್ಯದಲ್ಲಿ ಈ ಎಚ್ಚರವನ್ನು ಕೊಟ್ಟಿದ್ದಾರೆ. ಪ್ರಾಚೀನ ಗ್ರಂಥಗಳು ಒಗಟಿನಂತೆ. ಅದರ ಮೇಲ್ನೋಟದ ಅರ್ಥವನ್ನು ತಿಳಿದುಕೊಂಡರೆ ಅಸಂಗತವಾಗುತ್ತದೆ. ಅಧ್ಯಾತ್ಮ ಗ್ರಂಥಗಳಲ್ಲಿ ನಮ್ಮನ್ನು ಆಭೂತಿಗೆ ಕೊಂಡೊಯ್ಯಲು ಈ ರೀತಿ ಒಗಟಿನ ಭಾಷೆಯನ್ನು (symbolic language) ಉಪಯೋಗಿಸಿದ್ದಾರೆ. ವೇದವೆನ್ನುವುದು ಸಾಂಕೇತಿಕ ಭಾಷೆ ಎನ್ನುವುದನ್ನು ಅರಿಯದಿದ್ದರೆ ಅಧ್ಯಾತ್ಮ ಚಿಂತನೆ ಅನರ್ಥವಾಗುತ್ತದೆ. ಈ ರೀತಿ ತಿಳಿಯದೇ ಮಾಡುವ ಸಾಧನೆಯಿಂದ ಏನೂ ಉಪಯೋಗವಿಲ್ಲ.\n\nಪ್ರಾಚೀನ ಗ್ರಂಥಗಳಲ್ಲಿ ಅನೇಕ ಕಥೆಗಳನ್ನು ಕಾಣುತ್ತೇವೆ. ಅದನ್ನು ಮೇಲ್ನೋಟದಲ್ಲಿ ನೋಡಿದರೆ ವಿನೋದವೆನಿಸುತ್ತದೆ. ಆದರೆ ಅದರ ತಿರುಳನ್ನು ಅರಿತರೆ ಜೀವನ ಸಾರ್ಥಕ. ಇದಕ್ಕೆ ಉತ್ತಮ ಉದಾಹರಣೆ ಗಣಪತಿಯ ಕಥೆ. \"ಪಾರ್ವತಿ ತನ್ನ ಮೈಯ ಮಣ್ಣಿನಿಂದ ಗಣಪತಿಯನ್ನು ನಿರ್ಮಿಸಿದಳು, ಆತನ ತಲೆಯನ್ನು ಶಿವ ಕಡಿದ, ನಂತರ ಆತನಿಗೆ ಉತ್ತರ ದಿಕ್ಕಿಗೆ ತಲೆ ಹಾಕಿದ ಆನೆಯ ತಲೆಯನ್ನು ಜೋಡಿಸಿದರು, ಕಡಬು ತಿಂದ ಗಣೇಶ ಹೊಟ್ಟೆಗೆ ಹಾವನ್ನು ಸುತ್ತಿಕೊಂಡ\". ಏನಿದರ ಅರ್ಥ? भागशः ಈ ಕಥೆಯನ್ನು ಕೇಳದವರಿಲ್ಲ; ಆದರೆ ಅರ್ಥ ತಿಳಿದವರು ಸಾವಿರಕ್ಕೆ ಒಬ್ಬರಿಲ್ಲ! ಈ ಕಥೆಯನ್ನು ಸೂಕ್ಷ್ಮವಾಗಿ ವಿಶ್ಲೇಷಿಸಿದರೆ ಮಾತ್ರ ನಮಗೆ ಕಥೆಯ ಮಹತ್ವ, ಪೂಜೆಯ ಮಹತ್ವ, ನಂಬಿಕೆಯ ಮಹತ್ವ ಅರಿಯುತ್ತದೆ. ಗಣಪತಿ ಆಕಾಶದ ದೇವತೆ. ಆಕಾಶ ಪಂಚ ಭೂತಗಳಲ್ಲಿ ಮಹತ್ತಾದದ್ದು. ಗಣಪತಿಯ ಸ್ಥಾನ ಇಪ್ಪತ್ತೊಂದನೆಯದು. ಅದಕ್ಕಾಗಿ ಆತನಿಗೆ ಇಪ್ಪತ್ತೊಂದು ಮೋದಕ ಅರ್ಪಣೆ. ಐದು ಅಂತಃಕರಣ, ಐದು ಜ್ಞಾನೇಂದ್ರಿಯ, ಐದು ಕರ್ಮೇಂದ್ರಿಯ, ಐದು ತನ್ಮಾತ್ರೆಗಳು(ಶಬ್ದ, ಸ್ಪರ್ಶ ರೂಪ ರಸ ಗಂಧ) ಇದರಿಂದ ಆಚೆಗೆ ಆಕಾಶ, ಗಾಳಿ, ಬೆಂಕಿ, ನೀರು, ಮಣ್ಣು. ಇಲ್ಲಿ ಆಕಾಶ ಇಪ್ಪತ್ತೊಂದನೇ ಮೆಟ್ಟಿಲಲ್ಲಿದೆ. ಇದು ಇಪ್ಪತ್ತೊಂದನೇ ತತ್ವ. ಗಣಪತಿಗಿಂತ ಮೊದಲ ಸ್ತರದಲ್ಲಿರುವ ತತ್ತ್ವಾಭಿಮಾನಿಗಳು ಇಪ್ಪತ್ತು ಮಂದಿ. ಬ್ರಹ್ಮ, ವಾಯು, ಗರುಡ, ಶೇಷ, ರುದ್ರ, ಇಂದ್ರ, ಕಾಮ, ಅಹಂಪ್ರಾಣ, ಅನಿರುದ್ಧ, ಸ್ವಾಯಂಭುವಮನು, ಬೃಹಸ್ಪತಿ, ದಕ್ಷಪ್ರಜಾಪತಿ, ಪ್ರವಹವಾಯು, ಚಂದ್ರ, ಸೂರ್ಯ, ಯಮಧರ್ಮ, ವರುಣ, ವಹ್ನಿ, ಮಿತ್ರ ಮತ್ತು ನಿರ್ಋತಿ. ಗಣಪತಿ ಇಪ್ಪತ್ತೊಂದನೆಯವನು.\n\nಇನ್ನು ಶಿವ ಪಾರ್ವತಿಯರು. ಇವರು ದಂಪತಿಗಳು. ಇಲ್ಲಿ ಶಿವ ಮನಸ್ಸಿನ ಅಭಿಮಾನಿ ಮತ್ತು ಪಾರ್ವತಿ ವಾಕ್ ದೇವತೆ. ಮನಸ್ಸು ಯೋಚಿಸಿದಂತೆ ಮಾತು. ಅದಕ್ಕಾಗಿ ಅವರದು ಅನ್ಯೋನ್ಯ ದಾಂಪತ್ಯ. ಶಬ್ದದ ಮೂಲ ಶಕ್ತಿ ಗಾಳಿ ಮತ್ತು ಆಕಾಶ. ಆಕಾಶ ಮತ್ತು ಗಾಳಿ ಇಲ್ಲದಿದ್ದರೆ ಶಬ್ದವಿಲ್ಲ. ನಮ್ಮ ಒಳಗಿನ ವಾಕ್ ನಾದವೇ ಪಾರ್ವತಿ- ಅದು ಶಬ್ದ ರೂಪದಲ್ಲಿ ಹೊರ ಹೊಮ್ಮುವುದೇ ಮಾತು. ಇದು ಮೂಲ ನಾದದ ಸ್ಥೂಲ ರೂಪ. ಮನುಷ್ಯನಿಗೆ ದೊಡ್ಡ ಆಪತ್ತು ಮಾತು. ಅಧ್ಯಾತ್ಮ ಸಾಧನೆಗೆ ಬೇಕಾಗಿರುವುದು ಮಾತಿಗಿಂತ ಹೆಚ್ಚಾಗಿ ಮೌನ. ತನ್ನತನದ ಅರಿವಿಲ್ಲದೇ (awareness of self), ಅಹಂಕಾರ ತತ್ವದ ವಿರುದ್ಧ ಮಾತು ಬೆಳೆದಾಗ, ಮಾತಿನ ಶಿರಭೇದನವಾಗದೇ ಜ್ಞಾನವಿಲ್ಲ. ಶಿರಭೇದನವಾದ ಮೇಲೆ ಪುನಃ ಅದೇ ಮಾತು ಮುಂದುವರಿಯಬಾರದು. ಅದಕ್ಕಾಗಿ ಎಲ್ಲವನ್ನು ಕೇಳುವ ದೊಡ್ಡ ಕಿವಿಯುಳ್ಳ, ಪ್ರಾಣಶಕ್ತಿಯನ್ನು ನಿಯಂತ್ರಿಸುವ ಉದ್ದನೆಯ ಮೂಗಿನ ಸಾಂಕೇತ ರೂಪವಾದ ಆನೆಯ ತಲೆಯನ್ನು ಇಟ್ಟು ಗಣಪತಿ ಎನ್ನುವ ಹೊಸ ಆಕಾರದ ಜನನವಾಯಿತು. ಗಣಪತಿಯನ್ನು ನೋಡಿದಾಕ್ಷಣ ನಮಗೆ ನೆನಪಿಗೆ ಬರಬೇಕಾದ ವಿಷಯ ಮಾತಿಗಿಂತ ಮನನ ಹೆಚ್ಚು ಮಾಡು, ಸರಿಯಾಗಿ ಕೇಳಿಸಿಕೋ (be a good listener) ಎನ್ನುವ ವಿಚಾರ.\n\nಇನ್ನು ಉತ್ತರ ದಿಕ್ಕಿಗೆ ತಲೆ ಹಾಕುವುದು ಅಂದರೆ ಏನು? ಸಾಮಾನ್ಯವಾಗಿ ನಮಗೆಲ್ಲರಿಗೂ ಗೊತ್ತಿರುವಂತೆ ಉತ್ತರಕ್ಕೆ ತಲೆ ಹಾಕಿ ಮಲಗಬಾರದು. ದಕ್ಷಿಣಕ್ಕೆ ಮುಖ ಮಾಡಿ ಪೂಜೆಗೆ ಕುಳಿತು ಕೊಳ್ಳಬಾರದು. ದೇವಸ್ಥಾನದಲ್ಲಿ ಅಪ್ರದಕ್ಷಿಣೆ ಸುತ್ತಬಾರದು ಇತ್ಯಾದಿ. ಆದರೆ ಈ ಎಲ್ಲಾ ವಿಚಾರ ಏಕೆ? ಇದರ ಹಿಂದಿರುವ ಸಿದ್ಧಾಂತ ಏನು? ಈ ಭೂಮಿಯಲ್ಲಿ ಉತ್ತರ ಧ್ರುವದ ಶಕ್ತಿ ಉತ್ತರದಿಂದ ಪೂರ್ವಕ್ಕೆ ಹರಿಯುತ್ತಿರುತ್ತದೆ. ಹಾಗೂ ದಕ್ಷಿಣ ಧ್ರುವದ ಶಕ್ತಿ ದಕ್ಷಿಣದಿಂದ ಪಶ್ಚಿಮಕ್ಕೆ ಹರಿಯುತ್ತಿರುತ್ತದೆ. ನಮ್ಮ ಚಲನೆ ಕೂಡಾ ಈ ಶಕ್ತಿಪಾತಕ್ಕೆ ಅನುಗುಣವಾಗಿರಬೇಕು. ನಾವು ದಕ್ಷಿಣಕ್ಕೆ ಮುಖ ಮಾಡಿದರೆ ದಕ್ಷಿಣ ಧ್ರುವದ ಶಕ್ತಿಪಾತಕ್ಕೆ ನಮ್ಮನ್ನು ನಾವು ಒಡ್ಡಿಕೊಂಡಂತೆ ಹಾಗೂ ಉತ್ತರಕ್ಕೆ ಮುಖ ಮಾಡಿದರೆ ಉತ್ತರ ಧ್ರುವದ ಶಕ್ತಿಪಾತಕ್ಕೆ ಒಡ್ಡಿಕೊಂಡಂತೆ. ಉತ್ತರಕ್ಕೆ ತಲೆ ಹಾಕಿ ಮಲಗುವುದು ಎಂದರೆ ಎದ್ದಾಗ ದಕ್ಷಿಣಕ್ಕೆ ಮುಖ ಮಾಡುವುದು. ಆದ್ದರಿಂದ ದಕ್ಷಿಣ ಮುಖ ಹಾಗೂ ಉತ್ತರ ತಲೆ ಎರಡೂ ಒಂದೇ. ಈ ಎರಡು ಶಕ್ತಿಪಾತದಲ್ಲಿ ಒಂದು ದೊಡ್ಡ ವ್ಯತ್ಯಾಸವಿದೆ. ಅದೇನೆಂದರೆ ಉತ್ತರದ ಶಕ್ತಿಪಾತ ಊರ್ಧ್ವಮುಖವಾದದ್ದು ಹಾಗೂ ದಕ್ಷಿಣದ ಶಕ್ತಿಪಾತ ಸಂಸಾರದ ಸುಳಿಯಲ್ಲಿ ಸಿಲುಕಿಸುವಂತಾದ್ದು. ಈ ಕಾರಣಕ್ಕಾಗಿ ಉತ್ತರಕ್ಕೆ ತಲೆ ಹಾಕಿ ಮಲಗಿದರೆ ಅಥವಾ ದಕ್ಷಿಣಕ್ಕೆ ಮುಖ ಮಾಡಿ ಪೂಜೆಗೆ ಕುಳಿತರೆ ನಮ್ಮ ಶಿರಛೇದನವಾಗುತ್ತದೆ. ನಾವು ಪುನಃ ಈ ಸಂಸಾರದ ಸುಳಿಯಲ್ಲಿ ಸುತ್ತಬೇಕಾಗುತ್ತದೆ.\n\nಇನ್ನು ಹೊಟ್ಟೆಗೆ ಹಾವಿನ ಸುತ್ತು. ಹಾವು ಕುಂಡಲಿನಿ ಶಕ್ತಿಯ ಸಂಕೇತ. ಇದು ಚಕ್ರಾಕಾರವಾಗಿ ತಲೆ ಕೆಳಗೆ ಹಾಕಿ ಮಲಗಿದ ಹಾವಿನ ರೂಪದಲ್ಲಿ ನಮ್ಮ ಮಲ-ಮೂತ್ರ ದ್ವಾರದ ಮಧ್ಯದಲ್ಲಿರುತ್ತದೆ. ಕುಂಡಲಿನಿ ಜಾಗೃತವಾಗುವುದು ಎಂದರೆ ಈ ಹಾವು ಹೆಡೆಯೆತ್ತಿ ನಿಲ್ಲುವುದು. ಕುಂಡಲಿನಿ ಜಾಗೃತವಾದಾಗ ಶಕ್ತಿ- ಮೂಲಾಧಾರ, ಮಣಿಪುರ ಹಾಗೂ ಸ್ವಾದಿಷ್ಠಾನ ಶಕ್ತಿ ಕೇಂದ್ರಗಳಲ್ಲಿ ಊರ್ಧ್ವ ಮುಖವಾಗಿ ಸಂಚರಿಸುತ್ತದೆ. ನಮ್ಮ ಹೊಕ್ಕುಳಿನ ಮೇಲಿನ ಶಕ್ತಿ ಕೇಂದ್ರ ಜ್ಞಾನದ ಬಾಗಿಲು, ಗಣಪತಿ ಈ ಮೂರು ಶಕ್ತಿ ಕೇಂದ್ರಗಳನ್ನು ನಿಯಂತ್ರಿಸಿ ನಮಗೆ ಜ್ಞಾನದ ಬಾಗಿಲನ್ನು ತೆರೆಯುವ ಶಕ್ತಿದೇವತೆ. ಇಷ್ಟೊಂದು ಸಂಗತಿ ಈ ಪುಟ್ಟ ಕಥೆಯಲ್ಲಿದೆ. ಇದು ಹೂವಿನಿಂದ ಹಣ್ಣಿಗೆ ಹೋಗುವ ರೀತಿ. ಕೇವಲ ಮೇಲ್ನೋಟದ ಅರ್ಥದಲ್ಲೇ ನಿಂತರೆ ತೊಂದರೆಯಿಲ್ಲ, ಅದರಿಂದಾಚೆಗೆ ಏನೂ ಇಲ್ಲ ಎಂದು ತಿಳಿದರೆ ಅದು ಅನರ್ಥ.\n\nನಾವು ನಮ್ಮ ತಲೆಯಲ್ಲಿದ್ದುದನ್ನು ವೇದದಲ್ಲಿ ಕಾಣದೆ, ವೇದದಲ್ಲಿದ್ದುದನ್ನು ತಲೆಯೊಳಗೆ ತುಂಬಿಕೊಳ್ಳಬೇಕು. ವೇದವನ್ನು ಮೇಲ್ನೋಟದಲ್ಲಿ ಕಂಡಾಗ ಕೇವಲ ಜನ್ಮ-ಕರ್ಮ, ಹುಟ್ಟು-ಸಾವು, ಈ ಸುಳಿಯಲ್ಲೇ ಇರುತ್ತೇವೆ, ಎಂದೂ ಅಮರತ್ವದ ದಾರಿ ಕಾಣದು. ಮೇಲ್ನೋಟಕ್ಕೆ ವೇದವನ್ನು ಕಾಣುವವರು ಬೆಳಗಿನಿಂದ ಸಂಜೆಯ ತನಕ ಭೋಗ ಐಶ್ವರ್ಯ ಕರ್ಮ ಕಲಾಪದಲ್ಲಿ ನಿಂತು ಆತ್ಮಸಾಕ್ಷಾತ್ಕಾರವನ್ನು ಮರೆತು ನಿಲ್ಲುತ್ತಾರೆ. ಇದು ದೊಡ್ಡ ದುರಂತ.\n\nಈಗ ನಮಗೆ ಒಂದು ಪ್ರಶ್ನೆ ಕಾಡುತ್ತದೆ. ಅದೇನೆಂದರೆ ಪ್ರಾಚೀನ ಅಧ್ಯಾತ್ಮ ಗ್ರಂಥಗಳನ್ನು ಏಕೆ ಒಗಟಿನ ರೂಪದಲ್ಲಿ ಬರೆದಿದ್ದಾರೆ? ಎಂದು. ತರಗತಿಗೊಂದು ಪಠ್ಯಪುಸ್ತಕವಿರುವಂತೆ ಈ ಗ್ರಂಥಗಳನ್ನು ಹಂತಹಂತವಾಗಿ ಅರ್ಥವಾಗುವ ರೀತಿ ಏಕೆ ಬರೆದಿಲ್ಲ? ಇತ್ಯಾದಿ. ಇಲ್ಲಿ ನಾವು ತಿಳಿದುಕೊಳ್ಳಬೇಕಾದ ಮುಖ್ಯ ವಿಷಯ ಏನೆಂದರೆ ಈ ಗ್ರಂಥಗಳನ್ನು ತಿಳಿದುಕೊಳ್ಳಲು ಯೋಗ್ಯತೆ ಬೇಕು. ಇಲ್ಲಿ ಪುಸ್ತಕ ಒಂದೇ; ಆದರೆ ಒಂದೇ ಪುಸ್ತಕದಲ್ಲಿ ಅನೇಕ ಹಂತದ ಶಿಕ್ಷಣ ಅಡಗಿದೆ. ಈ ವೇದ ಗ್ರಂಥಗಳು ಎಂದೂ ಅಯೋಗ್ಯರಿಗೆ ದಕ್ಕದು. ಅವು ಕೇವಲ ತನ್ನನ್ನು ಅರಿಯಬಲ್ಲ, ಅರಿತು ಅದರ ಸದುಪಯೋಗ ಮಾಡಬಲ್ಲವನ ಮುಂದೆ ಮಾತ್ರ ತೆರೆದುಕೊಳ್ಳುತ್ತವೆ. ಯೋಗ್ಯನಾದವನು ಈ ಗ್ರಂಥದ ಆಳಕ್ಕಿಳಿದಷ್ಟೂ ಹೆಚ್ಚು ಹೆಚ್ಚು ವಿಷಯ ತಿಳಿಯುತ್ತಾನೆ. ಒಂದು ಗ್ರಂಥವನ್ನು ಅರಿಯಲು ಅನೇಕ ಜನ್ಮಗಳ ಸಾಧನೆ ಬೇಕು.",
  "2.45": "ತ್ರೈಗುಣ್ಯ ವಿಷಯಾಃ ವೇದಾಃ ನಿಸ್ತ್ರೈಗುಣ್ಯಃ ಭವ ಅರ್ಜುನ |\nನಿರ್ದ್ವಂದ್ವಃ ನಿತ್ಯಸತ್ತ್ವಸ್ಥಃ ನಿರ್ಯೋಗಕ್ಷೇಮಃ ಆತ್ಮವಾನ್‌ -- ವೇದಗಳು ಹೊರನೋಟಕ್ಕೆ ತ್ರಿಗುಣಗಳ ನಂಟನ್ನೇ\nನಿರೂಪಿಸುತ್ತವೆ. [ಒಳಗಿನಿಂದ ತ್ರಿಗುಣಗಳ ನಂಟಿನ ನಂಜನ್ನು ನಿವಾರಿಸುತ್ತವೆ]. ಓ ಅರ್ಜುನಾ, ನೀನು\nತ್ರಿಗುಣಗಳ ನಂಟನ್ನು ನೀಗಿ ನಿಲ್ಲು... ದ್ವಂದ್ವಗಳ ತಾಕಲಾಟ ತೊಡೆದು ಸದಾ ಭಗವಂತನಲ್ಲಿ ಬಗೆಯನ್ನಿಡು.\nಯೋಗ-ಕ್ಷೇಮದ ಹೊಣೆಯನ್ನು ಅವನಿಗೊಪ್ಪಿಸಿ ಅವನೇ ಸ್ವಾಮಿ ಎಂದು ನಂಬಿ ನಡೆ.\n\nಈವರೆಗೆ ನಾವು ವೇದವನ್ನು ಹೇಗೆ ಅನುಸಂಧಾನ ಮಾಡಬೇಕು, ಅದರ ಮೇಲ್ನೊ ೀಟದ ಅರ್ಥದಿಂದ ಆಳಕ್ಕೆ\nಹೇಗೆ ಇಳಿಯಬೇಕು ಎನ್ನುವುದನ್ನು ಕೃಷ್ಣ ಅರ್ಜುನನಿಗೆ ಹೇಳಿದ್ದನ್ನು ನೋಡಿದೆವು. ಇನ್ನಷ್ಟು ಸ್ಪಷ್ಟವಾಗಿ , ಅದು\nಹೇಗೆ ಕಾಣುತ್ತದೆ ಹಾಗೂ ಅದನ್ನು ಹೇಗೆ ನೋಡಬೇಕು ಎನ್ನುವುದನ್ನು ಈ ಶ್ಲೋಕದಲ್ಲಿ ಕೃಷ್ಣ ಸ್ಪಷ್ಟವಾಗಿ\nವಿವರಿಸುತ್ತಾನೆ. ಇದು ಒಂದು ರೀತಿಯಲ್ಲಿ ಇಡೀ ಅಧ್ಯಾತ್ಮದ ಅನುಸಂಧಾನದ ಪ್ರಮುಖವಾದ ವಿಚಾರ. ಇಲ್ಲಿ\nಕೃಷ್ಣ ಅದನ್ನು ಹೇಗೆ ಅನುಸಂಧಾನ ಮಾಡಬೇಕು, ಹಾಗೂ ನಮ್ಮ ಮನಸ್ಸನ್ನು ಹೇಗೆ ಅಣಿಗೊಳಿಸಬೇಕು\nಎನ್ನುವುದನ್ನು ವಿವರಿಸಿದ್ದಾನೆ.\n\nನಮಗೆ ಮೇಲ್ನೋಟಕ್ಕೆ ವೇದ ಸತ್ವ-ರಜಸ್ಸು-ತಮೋಗುಣಗಳಿಗೇ(ತ್ರೈಗುಣ್ಯ) ಸಂಬಂಧಪಟ್ಟ ಪ್ರಾಪಂಚಿಕ ವಿಷಯ,\nಹಾಗೂ ಕೇವಲ ಪ್ರಾಪಂಚಿಕ ಅರ್ಥವನ್ನೇ ಹೇಳುವಂತೆ ಕಾಣುತ್ತದೆ-ಕೆಂಪು ಕನ್ನಡಕ ಧರಿಸಿದವನಿಗೆ\nಪ್ರಪಂಚವೆಲ್ಲಾ ಕೆಂಪಾಗಿ ಕಾಣುವಂತೆ. ಉದಾಹರಣೆಗೆ: ಸಂತಾನ ವೃದ್ಧಿ, ಹಟ್ಟಿ ತುಂಬಾ ಹಸು, ಕೈತುಂಬಾ\nದುಡ್ಡು, ಮನೆತುಂಬಾ ಮಕ್ಕಳು, ರಾಜಸೂಯ, ಅಶ್ವಮೇಧ, ಪುರುಷಮೇಧ ಇತ್ಯಾದಿ. ಇವು ವೇದದಲ್ಲಿ\nಮೇಲ್ನೋಟಕ್ಕೆ ಕಾಣುವವು. ಇವೆಲ್ಲವೂ ತೀರಾ ಪ್ರಾಪಂಚಿಕ ವಿಷಯಗಳು. ಇದರಿಂದಾಗಿ ವೇದ ನಮ್ಮನ್ನು\nಅಧ್ಯಾತ್ಮದ ಆಳಕ್ಕೆ ಕೊಂಡೊಯ್ಯುವುದಿಲ್ಲ ಎನ್ನು ವಂತೆ ಭಾಸವಾಗುತ್ತದೆ. ಆದರೆ ನಾವು ವೇದವನ್ನು ಅರ್ಥ\nಮಾಡಿಕೊಳ್ಳಬೇಕಾದರೆ ಮೊದಲು ಪ್ರಾಪಂಚಿಕ ಪ್ರಭಾವವನ್ನು ದಾಟಿ ನಿಲ್ಲಬೇಕು. ಪ್ರಾಪಂಚಿಕ ಪ್ರಭಾವ ಕೆಂಪು\nಕನ್ನಡಕದಂತೆ. ಅದರ ಪ್ರಭಾವದಲ್ಲಿ ವೇದವನ್ನು ಕಂಡರೆ ನಮಗೆ ಕಾಣುವುದು ಕೇವಲ ಪ್ರಾಪಂಚಿಕ ವಿಷಯ\nಮಾತ್ರ. ಅದಕ್ಕಾಗಿ ನಾವು ತ್ರೈಗುಣ್ಯವರ್ಜಿತರಾಗಬೇಕು. ಈ ತ್ರೈಗುಣ್ಯದ ಪ್ರಭಾವವನ್ನು ದಾಟಿ ನಮ್ಮ ನಿಜವಾದ\nಸ್ವಭಾವ ಏನು ಎನ್ನುವುದನ್ನು ಗುರುತಿಸಿಕೊಂಡಾಗ ಶುದ್ಧ ಚಿಂತನೆ ಸಾಧ್ಯ. ತ್ರಿಗುಣದ ಬೇಲಿಯನ್ನು ದಾಟದೇ\nಸತ್ಯ ತಿಳಿಯುವುದಿಲ್ಲ. ತ್ರಿಗುಣದ ಪ್ರಭಾವದಿಂದ ಪೂರ್ಣ ಆಚೆಗೆ ನಿಲ್ಲುವುದು ಅಸಾಧ್ಯ. ಆದರೆ ಈ ವಿಷಯ\nಗೊತ್ತಿದ್ದು ಅದರ ಎಚ್ಚರ ಇದ್ದರೆ ನಾವು ಸಾಧನೆ ಮಾಡಲು ಸಾಧ್ಯ. ನಾವು ಎಷ್ಟು ಅಪವಿತ್ರರಾಗಿರಲೀ,\nಬಾಯಿಯಲ್ಲಿ ಭಗವಂತನ ನಾಮ ಸ್ಮರಣೆ, ನಮ್ಮೊಳಗೆ ಭಗವಂತನಿದ್ದಾನೆ ಎನ್ನುವ ಎಚ್ಚರ ನಮ್ಮನ್ನು\nಶುದ್ಧವಾಗಿಸುತ್ತದೆ.\n\nಧ್ಯಾನ ಮಾಡುವಾಗ ನಮ್ಮ ಮನಸ್ಸು ಹೊರ ಪ್ರಪಂಚದತ್ತ ಸುಳಿಯದಂತೆ ನೋಡಿಕೊಳ್ಳಬೇಕು.\nಆತ್ಮಜ್ಞಾನವಿಲ್ಲದೆ ಹೋಮ ಹವನ ಮಾಡಿ ಉಪಯೋಗವಿಲ್ಲ. ನಮಗೆ ಆಶ್ರಯವಾಗಿರುವ ಆತ್ಮತತ್ವ ಭಗವಂತನ\nಅರಿವಿನಿಂದ-ನಿಸ್ವಾರ್ಥವಾಗಿ ಸಾಧನೆ ಮಾಡಬೇಕು. ಎಂದೂ ಕಪಟ ವಂಚನೆ ಇಲ್ಲದ ಧರ್ಮವನ್ನು\n\nಆಚರಿಸಬೇಕು. ನಮ್ಮ ಮನಸ್ಸನ್ನು ಶುದ್ಧ ಭಾವ ಚಿಂತನೆಗೆ ಅಣಿಗೊಳಿಸಬೇಕು. ನಮ್ಮ ಸ್ವಾರ್ಥದತ್ತ ನೋಡದೇ,\nತ್ರಿಗುಣಗಳನ್ನು ದಾಟಿ ನಿಂತರೆ ಮಾತ್ರ ನಮಗೆ ವೇದದ ನಿಜ ಸಂದೇಶ ತಿಳಿಯುತ್ತದೆ. ಈ ಸ್ಥಿತಿಯಲ್ಲಿ ವೇದ\nಓದಿದರೆ ಅದು ಕೇವಲ ಲೌಕಿಕ ವಿಷಯವಲ್ಲ ಎನ್ನುವುದು ಅರ್ಥವಾಗುತ್ತದೆ. ನಾವು ಮಾಡುವ ಪ್ರತಿಯೊಂದು\nಕರ್ಮವನ್ನು, ಪೂಜೆ. ಪುನಸ್ಕಾರವನ್ನು, ನಿಸ್ವಾರ್ಥವಾಗಿ ಭಗವಂತನ ಆರಾಧನೆ ಎಂದು ಮಾಡಬೇಕು.\nನಮಗೇನು ಬೇಕು ಅನ್ನುವುದು ನಮಗೆ ಗೊತ್ತಿಲ್ಲ; ನಮಗೆ ಅಗತ್ಯವಾದದ್ದನ್ನು ಭಗವಂತ ಕೊಟ್ಟೇ ಕೊಡುತ್ತಾನೆ;\nಎಂದು ನಮ್ಮ ಭವಿಷ್ಯದ ಚಿಂತೆಯನ್ನು ಭಗವಂತನಿಗೊಪ್ಪಿಸಿ ಮುನ್ನೆಡೆದರೆ ಜ್ಞಾನ ಸಿದ್ಧಿಯಾಗುತ್ತದೆ.\n\nಇಲ್ಲದ್ದನ್ನು ಪಡೆಯುವುದು ಯೋಗ, ಪಡೆದದ್ದನ್ನು ಉಳಿಸಿಕೊಳ್ಳುವುದು ಕ್ಷೇಮ. ಲೌಕಿಕವಾದ ಯೋಗ ಕ್ಷೇಮದಲ್ಲೇ\nನಮ್ಮ ಇಡೀ ಜೀವನ ಕಳೆದು ಹೋಗುತ್ತದೆ. ಇದನ್ನು ಬಿಟ್ಟು ಭಗವಂತ ನಮಗೆ ಏನು ಕೊಟ್ಟಿದ್ದಾನೋ ಅದರಲ್ಲಿ\nಸಂತೋಷವಾಗಿರಲು ಕಲಿಯಬೇಕು. 'ನಿರ್ಯೋಗಕ್ಷೇಮದ' ಸ್ಥಿತಿಯಲ್ಲಿ ಮಾತ್ರ ಸತ್ಯದ ಸಾಕ್ಷಾತ್ಕಾರವಾಗುತ್ತದೆ.\nನಮ್ಮ ಯೋಗಕ್ಷೇಮದ ಹೊಣೆ ಆ ಭಗವಂತನದ್ದು. ಎಲ್ಲರೊಳಗೆ ಅಂತರ್ಯಾಮಿಯಾಗಿರುವ ಭಗವಂತ\nಎಂದೆಂದೂ ನಮ್ಮನ್ನು ರಕ್ಷಿಸುತ್ತಾನೆ ಎನ್ನುವ ಭರವಸೆಯಿಂದ, ಭಗವಂತನ ಚಿಂತನೆಗೆ ತೊಡಗಬೇಕು. ಇದು\nಅಧ್ಯಾತ್ಮ ಸಾಧನೆಗೆ ಬೇಕಾದ ಮಾನಸಿಕ ತಯಾರಿ. ಇಂತಹ ಮನಃಸ್ಥಿತಿಯಲ್ಲಿ ಯಾವ ಗ್ರಂಥ ಓದಿದರೂ ಅದು\nಭಗವಂತನ ಸ್ತುತಿಯಾಗುತ್ತದೆ. ಈ ಮನಃಸ್ಥಿತಿ ತಲುಪದೇ ವೇದಾಂತ ನಮಗೆ ಅರ್ಥವಾಗುವುದಿಲ್ಲ.\n\nಅಧ್ಯಾತ್ಮ ಮಾರ್ಗದಲ್ಲಿ ಸಾಗುವ ವ್ಯಕ್ತಿಯ ಸಾಧನೆ ಏನಿರಬೇಕು, ಅಂತರಂಗದ ಅನುಷ್ಠಾನ ಹೇಗಿರಬೇಕು,\nಎನ್ನುವುದನ್ನು ಸ್ಪಷ್ಟಪಡಿಸಿದ ಕೃಷ್ಣನ ಮಾತಿನಿಂದ ನಮಗೆ ಒಂದು ಪ್ರಶ್ನೆ ಮೂಡಬಹುದು. ಕೃಷ್ಣ ಕರ್ಮ ಮತ್ತು\nಜ್ಞಾನಗಳಲ್ಲಿ- ಜ್ಞಾನಕ್ಕೆ ಒತ್ತುಕೊಟ್ಟು ಸಾಗಬೇಕು, ನಮ್ಮ ಯಾವುದೇ ಕ್ರಿಯೆಯ ಅನುಸಂಧಾನ ಜ್ಞಾನದ ಕಡೆಗೆ\nಪೂರಕವಾಗಿರಬೇಕು ಎನ್ನುತ್ತಾನೆ. “ಏಕೆ ಜ್ಞಾನ ಸಾಧನೆಗೆ ಇಷ್ಟೊಂದು ಮಹತ್ವ? ಕರ್ಮಯೋಗದಿಂದ\nಸ್ವರ್ಗವನ್ನು ಪಡೆಯಬಹುದಲ್ಲ? ಎನ್ನುವ ಪ್ರಶ್ನೆ. ಈ ಪ್ರಶ್ನೆಗೆ ಕೃಷ್ಣ ಇಲ್ಲಿ ಉತ್ತರಿಸುತ್ತಾನೆ. ಹಿಂದೆ ವೇದವನ್ನು\nಜ್ಞಾನಕಾಂಡ, ಕರ್ಮಕಾಂಡ ಮತ್ತು ಉಪಾಸನಕಾಂಡ ಎಂದು ಮೂರು ವಿಭಾಗ ಮಾಡಿದ ಪರಂಪರೆ ಇತ್ತು.\nಆದರೆ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ, ವೇದಕ್ಕೆ ಇರುವುದು ಒಂದೇ ಮುಖ ಎಂದು. ವೇದದಲ್ಲಿ ಹೇಳುವ ಕರ್ಮ, ಉಪಾಸನೆ,\nಎಲ್ಲವುದರ ಹಿಂದೆ ಜ್ಞಾನವಡಗಿದೆ. ಎಲ್ಲವೂ ಜ್ಞಾನಕ್ಕೋಸ್ಕರ. ಆದ್ದರಿಂದ ಇಡೀ ವೇದವೇ ಜ್ಞಾನಕಾಂಡ ಎಂದು\nಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ಕೃಷ್ಣ ಒತ್ತಿ ಹೇಳುತ್ತಾನೆ.\n",
  "2.46": "ಯಾವಾನ್‌ ಅರ್ಥಃ ಉದಪಾನೇ ಸರ್ವತಃ ಸಂಪ್ಸುತ ಉದಕೇ |\n\nತಾವಾನ್‌ ಸರ್ವೇಷು ವೇದೇಷು ಬ್ರಾಹ್ಮಣಸ್ಯ ವಿಜಾನತಃ -- ಬಾವಿಯಿಂದ ಏನೇನು ಉಪಯೋಗವಿದೆಯೋ\nಅದೆಲ್ಲವೂ ತುಂಬಿ ಹರಿಯುವ ನೀರ ನೆಲೆಯಲ್ಲಿ ಒಳಗೊಂಡಿದೆ. ಎಲ್ಲಾ ವೇದಗಳಲ್ಲಿ ಏನು ಫಲವೋ ಅದು\nಬ್ರಹ್ಮವನ್ನು ಬಲ್ಲ ವಿಜ್ಞಾನಿಯ ಫಲದಲ್ಲಿ ಒಳಗೊಂಡಿದೆ.[ಪ್ರಕೃತಿಯೇ ನೀರಂತೆ ಎಲ್ಲೆಡೆ ತುಂಬಿ ಹರಿಯುವ\n\nಪ್ರಳಯದಲ್ಲಿ ಕೂಡಾ ತುಂಬಿದ ಕೊಡವಾಗಿ, ಇನ್ನೊ ಬ್ಬರ ಕಾಪಿಗೊಳಪಡದೇ, ಕಾಲಾದಿಗಳನ್ನು ನಿಯಮಿಸುವ\nಭಗವಂತನಿಂದ ಎನಿತು ಲಭ್ಯವೋ -ಅದು ಎಲ್ಲಾ ವೇದಗಳನ್ನು ಬಲ್ಲ ಹಿರಿಯ ಜ್ಞಾನಿಗೆ ಮಾತ್ರ ಸುಲಭ]\n\nಈ ಶ್ಲೋಕ ಒಗಟಿನಂತಿದೆ. ನೇರವಾಗಿ ನೋಡಿದರೆ ಅರ್ಥ ತಿಳಿಯದ ಶ್ಲೋಕವಿದು.ಈ ಶ್ಲೋಕವನ್ನು ಅರ್ಥ\nಮಾಡಿಕೊಳ್ಳಬೇಕಾದರೆ ಸಾವು ಶ್ಲೋಕದಲ್ಲಿ ಮುಳುಗಬೇಕು. ಆಗ ಆಳದಲ್ಲಿನ ಮುತ್ತು ರತ್ನಗಳು ನಮಗೆ\nಸಿಗುತ್ತವೆ. ನಾವು ನಮ್ಮ ಅಹಂಕಾರವನ್ನು ಸಂಪೂರ್ಣ ತೊರೆದು ಶರಣಾಗತಿಯಿಂದ(Self Surrender)\nನೋಡಿದಾಗ ಅದು ತನ್ನನ್ನು ತೆರೆದುಕೊಳ್ಳುತ್ತದೆ. ಈ ಶ್ಲೋಕವನ್ನು ಸ್ವಲ್ಪ ಬಿಡಿಸಿ ಹೀಗೆ ಹೇಳಬಹುದು:\n\nಯಾವಾನ್‌ ಅರ್ಥ ಉದಪಾನೇ ಯಾವಾನ್‌ ಅರ್ಥ ಸರ್ವತಃ ಸಂಪ್ಗತೋದಕೇ\n\nತಾವಾನ್‌ ಸರ್ವೇಷು ವೇದೇಷು ತಾವಾನ್‌ ಬ್ರಾಹ್ಮಣಸ್ಯ ವಿಜಾನತಃ\nಒಂದು ಬಾವಿ ತೋಡಿ ಅದರಲ್ಲಿ ಬರುವ ನೀರಿನಿಂದ ಏನು ಪ್ರಯೋಜನವೋ, ಆ ಎಲ್ಲಾ ಪ್ರಯೋಜನಗಳ\nಜೊತೆಗೆ ಇನ್ನೂ ಅನೇಕಾನೇಕ ಪ್ರಯೋಜನಗಳನ್ನು ತುಂಬಿ ಹರಿಯುವ ನೀರಿನ ನೆಲೆ ಕೊಡಬಲ್ಲದು.\nಜ್ಞಾನವಿಲ್ಲದೆ ಕರ್ಮ ಕಾಂಡವನ್ನು ಮಾಡುವವನ ಸ್ಥಿತಿ ಮನೆಯಲ್ಲಿ ಕಷ್ಟಪಟ್ಟು ಬಾವಿ ತೋಡಿ ಅದರಿಂದ ನೀರು\nಸೇದಿದಂತೆ. ಭಗವಂತನನ್ನು ಸಾಕ್ಷಾತ್ಕ್ಮಾರಗೊಳಿಸಿಕೊಂಡವನ ಸ್ಥಿತಿ ತುಂಬಿ ಹರಿಯುವ ನೀರಿನ ನೆಲೆಯ\nದಡದಲ್ಲಿದ್ದಂತೆ. ಅಪರೋಕ್ಷ ಜ್ಞಾನಿ ಎಲ್ಲವುದರಲ್ಲೂ ಭಗವಂತನನ್ನು ಕಾಣುತ್ತಾನೆ. ಬ್ರಹ್ಮಜ್ಞಾನಿ ಸದಾ\nನಿರ್ಮಲವಾಗಿ ತುಂಬಿ ಹರಿಯುವ ನೀರಿನ ನೆಲೆಯ ಪಕ್ಕ ನಿಂತವನಂತೆ. ಇಡೀ ವೇದವನ್ನು ಓದಿ ಕರ್ಮದಲ್ಲೇ\nಕುಳಿತವನು ಬೆವರು ಸುರಿಸಿ ಬಾವಿಯಿಂದ ನೀರು ಸೇದುವವನಂತೆ.\nಈ ಶ್ಲೋಕದಲ್ಲಿ 'ಬ್ರಾಹ್ಮಣ' ಎನ್ನುವ ಪದ ಬಂದಿದೆ. ಇದನ್ನು 'ಜಾತಿ' ಎಂದು ಪರಿಗಣಿಸಿದರೆ ಈ ಶ್ಲೋಕದ ನಿಜ\nಸಂದೇಶ ತಿಳಿಯುವುದಿಲ್ಲ. ವೇದ ಗ್ರಂಥಗಳಲ್ಲಿ ಎಲ್ಲೂ ಜಾತಿಯ ಬಗ್ಗೆ ಪ್ರಸ್ತಾಪವಿಲ್ಲ. ಬ್ರಾಹ್ಮಣ ಅಂದರೆ 'ಬ್ರಹ್ಮ\nಅಣತೀತಿ'; ಅಂದರೆ ಬ್ರಹ್ಮ ತತ್ವವನ್ನು ಅರ್ಥ ಮಾಡಿಕೊಂಡವ ಎಂದರ್ಥ. 'ಬ್ರಹ್ಮ' ಎಂದರೆ ಎಲ್ಲಕ್ಕೆಂತ\nದೊಡ್ಡದಾದದ್ದು. ಎಲ್ಲಕ್ಕಿಂತ ದೊಡ್ಡದು ವೇದ ಮತ್ತು ವೇದವೇದ್ಯನಾದ ಭಗವಂತ. ಆದ್ದರಿಂದ ವೇದವನ್ನು\nಅರಿತವನು, ವೇದವೇದ್ಯ ಭಗವಂತನನ್ನು ಸಾಕ್ಷಾತ್ಮರಿಸಿಕೊಂಡವನು ಬ್ರಾಹ್ಮಣ.\nಬ್ರಹ್ಮನನ್ನು ಅಪರೋಕ್ಷವಾಗಿ ತಿಳಿದ ಜ್ಞಾನಿಗೆ ತುಂಬಿ ಹರಿವ ನೀರಿನ ಫಲವಾದರೆ, ಕರ್ಮಕನಿಗೆ ಬಾವಿಯ ಫಲ.\nಶಾಸ್ತ್ರದಿಂದ ವಿಶಿಷ್ಟವಾದ ಅರಿವನ್ನು ಪಡೆದ ವಿಜ್ಞಾನಿ ಮಾತ್ರ ಭಗವಂತನನ್ನು ಕಾಣಬಲ್ಲ. ಇಲ್ಲಿ ವಿಜ್ಞಾನಿ ಅಂದರೆ\nಯಾವುದೇ ಒಂದು ವಸ್ತುವಿನ ಬಗ್ಗೆ ತಳಸ್ಪರ್ಶಿ ಜ್ಞಾನ ಉಳ್ಳವನು ಎಂದರ್ಥ.\nಈ ಶ್ಲೋಕದಲ್ಲಿ ಇನ್ನೊಂದು ವಿಷಯವಡಗಿದೆ. \"ಸರ್ವತಃ ಸಂಪ್ಲ್ಗತೋದಕ”\" ಎಂದರೆ ನೀರು ತುಂಬಿದ ಸ್ಥಿತಿ. ಇಲ್ಲಿ\nನೀರು ಎಂದರೆ ಪ್ರಳಯಜಲ. ಪ್ರಕೃತಿ ಸೂಕ್ಷ್ಮವಾದ ಪರಮಾಣುವಿನ ಸಮುದ್ರ ರೂಪದಲ್ಲಿರುವ ಕಾಲ-ಪ್ರಳಯ\nಕಾಲ. ಇಂತಹ ಪ್ರಳಯ ಸಮುದ್ರದಲ್ಲಿ ಮಲಗಿರುವವ 'ಉದಪಾನ'. ಉತ್‌-ಅಪ-ಪಾನ-ಅಂದರೆ ಎಲ್ಲಕ್ಕಿಂತ\nಉತ್ಕೃಷ್ಟವಾದ, ಸದಾ ಎಚ್ಚರದಿಂದಿರುವ(ಉತ್‌); ಎಲ್ಲರನ್ನು ಪಾಲಿಸುವ, ಹಾಗೂ ತನಗೆ ಹಿರಿದಾದ ಇನ್ನೊಬ್ಬ\nಪಾಲಕನಿಲ್ಲದ ಸರ್ವೋತ್ತಮ(ಅಪ); ಎಲ್ಲರನ್ನೂ ನಿಯಂತ್ರಿಸುವ ಸರ್ವಚೇಷ್ಟಕ(ಅನ). ಈ ತತ್ವದ ಮೂಲಕ\nಏನೇನು ಉಪಯೋಗವನ್ನು ಪಡೆಯಬಹುದೋ ಆ ಉಪಯೋಗವನ್ನು ಸಮಸ್ತ ವೇದದಲ್ಲಿ, ವೇದದ\n\nಒಂದೊಂದು ಮಂತ್ರದಲ್ಲಿ, ಮಂತ್ರದ ಒಂದೊಂದು ವಾಕ್ಯದಲ್ಲಿ, ವಾಕ್ಯದ ಒಂದೊಂದು ಪದದಲ್ಲಿ, ಪದದ\nಒಂದೊಂದು ಅಕ್ಷರದಲ್ಲಿ ಭಗವಂತನನ್ನು ಕಾಣುವ ಬ್ರಹ್ಮಜ್ಞಾನಿ ಪಡೆಯುತ್ತಾನೆ.\n\nವೇದವನ್ನು ಕೇವಲ ಮೇಲ್ನೋಟದಲ್ಲಿ ಓದಿದರೆ ಅದರಿಂದ ಏನೂ ಉಪಯೋಗವಿಲ್ಲ. ವೇದದ ಸಮಗ್ರ\nಮಂತ್ರದಲ್ಲಿ, ಮಂತ್ರದ ಒಂದೊಂದು ಅಕ್ಷರದಲ್ಲಿ ಭಗವಂತನನ್ನು ಕಂಡು ಭಗವನ್ಮಯನಾದಾಗ, ಭಗವಂತನ\nಸಮಸ್ತ ಅನುಗ್ರಹಕ್ಕೆ ಪಾತ್ರನಾಗಿ, ಸಮಗ್ರ ಉಪಯೋಗವನ್ನು ಪಡೆಯಬಹುದು.\n\n“ಫಲ ಕಾಮನೆಯಿಂದ ಕರ್ಮಕಾಂಡ ಬೇಡ, ಸಮಗ್ರವೇದವನ್ನು ಭಗವಂತನ ಚಿಂತನೆಗೆ ಮೀಸಲಿಡಿ” ಎಂದು\nಹೇಳಿದ ಕೃಷ್ಣನ ಮಾತಿನಿಂದ ನಮಗೆ ಸ್ವಲ್ಪ ಗೊಂದಲವಾಗಬಹುದು. ಏಕೆಂದರೆ ವೇದದಲ್ಲಿ ಪ್ರತಿಯೊಂದು ಕಡೆ\nಫಲವನ್ನು ಹೇಳಿದ್ದಾರೆ. ಏಕೆ ಹೀಗೆ ಎನ್ನುವ ಪ್ರಶ್ನೆ ನಮ್ಮಲ್ಲಿ ಮೂಡುತ್ತದೆ. ಈ ಹಿಂದೆ ಹೇಳಿದಂತೆ ಅಧ್ಯಾತ್ಮದ\nಪಠ್ಯಪುಸ್ತಕ ಸಾಧನೆಯ ಎಲ್ಲಾ ಹಂತದಲ್ಲೂ-ಚಿಕ್ಕವರಿಂದ ದೊಡ್ಡವರಿಗೆ ಎಲ್ಲರಿಗೂ ಒಂದೆ. ಇನ್ನೂ ಆರಂಭದ\nಹಂತದಲ್ಲಿರುವವರಿಗೆ ಏನನ್ನೂ ಬಯಸದೇ ನಿರ್ಲಿಪ್ತರಾಗಿ ಅನುಸರಿಸಿ ಎಂದು ಹೇಳಿದರೆ ಅವರಿಗೆ ವೇದಾಂತದ\nಬಗ್ಗೆ ಆಸಕ್ತಿಯೇ ಬಾರದಿರಬಹುದು. ಅದಕ್ಕಾಗಿ, ಮಕ್ಕಳಿಗೆ ಬೆಲ್ಲ ಕೊಟ್ಟು ಔಷಧ ಕುಡಿಸಿದಂತೆ ವೇದಗಳಲ್ಲಿ\nಫಲವನ್ನು ಹೇಳಿದ್ದಾರೆ. ಇದು ವೇದಾಭ್ಯಾಸದ ಆರಂಭದ ಹಂತದಲ್ಲಿ ಉಪಯುಕ್ತ.\n\nಕರ್ಮ ಮಾಡುವಾಗ ನಮ್ಮ ಮನಃಸ್ಥಿತಿ ಹೇಗಿರಬೇಕು ಎನ್ನು ವುದನ್ನು ಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ಕೃಷ್ಣ ವಿವರವಾಗಿ\nಹೇಳಿದ್ದಾನೆ.",
  "2.47": "ಕರ್ಮಣಿ ಏವ ಅಧಿಕಾರಃ ತೇ ಮಾ ಫಲೇಷು ಕದಾಚನ |\n\nಮಾ ಕರ್ಮಫಲ ಹೇತುಃ ಭೂಃ ಮಾ ತೇ ಸಂಗಃ ಅಸ್ತು ಅಕರ್ಮಣಿ --ಕರ್ಮದಲ್ಲಿ ಮಾತ್ರ ನಿನಗೆ ಹಕ್ಕು, ಫಲಗಳಲ್ಲಿ\nಎಂದೂ ಇಲ್ಲ. ಫಲವನ್ನೇ ನಂಬಿ ಕರ್ಮ ಮಾಡಬೇಡ (ಕರ್ಮಕ್ಕೆ ಫಲ ನೀಡುವ ಶಕ್ತಿ ತಾನೆಂದು ಭ್ರಮಿಸಬೇಡ).\nಅಂತೆಯೇ ನಿಷ್ಕ ಯತೆ ನಿನಗಂಟದಿರಲಿ.\n\nಈ ಶ್ಲೋಕವನ್ನು ಅಪಾರ್ಥ ಮಾಡಿಕೊಳ್ಳುವವರೇ ಹೆಚ್ಚು. ಕರ್ಮ ಮಾಡಬೇಕು ಆದರೆ ಫಲವನ್ನು ಬಯಸಬಾರದು\nಅಂದರೆ ಏನು? ಇದು ಮನುಷ್ಯನನ್ನು ನಿಷ್ಕ ಯಗೊಳಿಸುತ್ತದೆ, ಎಂಬಿತ್ಯಾದಿ ವಾದಗಳನ್ನು ಈ ಶ್ಲೋಕದ ಮೇಲೆ\nಅನೇಕ ಮಂದಿ ಮಂಡಿಸಿದ್ದಾರೆ. ಆದರೆ ಅವರ್ಯಾರೂ ಶ್ಲೋಕದ ನಿಜವಾದ ಅರ್ಥವನ್ನು ತಿಳಿಯಲು\nಪ್ರಯತ್ನಿ ಪಿಲ್ಲ. ಇಲ್ಲಿ ಫಲವನ್ನು ಬಯಸಬೇಡ ಎಂದು ಎಲ್ಲಿಯೂ ಹೇಳಿಲ್ಲ. ಅದಕ್ಕೆ ಬದಲಾಗಿ ಫಲದಲ್ಲಿ ಅಧಿಕಾರ\nಸಾಧಿಸಬೇಡ ಎಂದಿದ್ದಾನೆ ಕೃಷ್ಣ.\n\nಕರ್ಮ ನಿನ್ನ ಕೈಯಲ್ಲಿದೆ- ಆದರೆ ಕರ್ಮ ಫಲ ಭಗವಂತನ ಕೈಯಲ್ಲಿದೆ. ನೀನು ನಾನೇ ಕರ್ಮ ಫಲದ ಹೇತು\nಎಂದು ತಿಳಿಯಬೇಡ. ಕರ್ಮಫಲದ ಹೇತು ಭಗವಂತ ಎನ್ನುವ ಎಚ್ಚರ ನಿನಗಿರಲಿ ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಇಲ್ಲಿ ಕೃಷ್ಣ\n\nಬಯಕೆಯನ್ನು ನಿರಾಕರಣೆ ಮಾಡಿಲ್ಲ, ಆದರೆ 'ಹೀಗೇ ಆಗಬೇಕು' ಇಲ್ಲದಿದ್ದರೆ ನಾನು ಈ ಕರ್ಮವನ್ನು ಮಾಡಲಾರೆ\nಎನ್ನುವ ಅಭಿಪ್ರಾಯ ಸರಿಯಲ್ಲ ಎಂದಿದ್ದಾನೆ. ಬಯಸುವ ಅಧಿಕಾರ ನಮಗಿದೆ ಆದರೆ ಫಲವನ್ನು ಕೊಡುವವ\nಭಗವಂತ ಎನ್ನುವ ಪರಿಜ್ಞಾನ ಬೇಕು. ಎಷ್ಟೋ ಸಲ ನಾವು ಅರಿವಿಲ್ಲದೇ ತಪ್ಪನ್ನು ಬಯಸುತ್ತೇವೆ. ಆಗ ಭಗವಂತ\nಅದನ್ನು ಕೊಡಲಾರ. ಏಕೆಂದರೆ ಯಾವುದು ಸರಿ, ಯಾವುದು ತಪ್ಪು ಎನ್ನುವ ಪರಿಜ್ಞಾನ ನಮಗಿಲ್ಲ. ಈ ಎಚ್ಚರ\nಇದ್ದರೆ ನಮಗೆ ಫಲ ಸಿಗದಿದ್ದಾಗ ದುಃಖವಾಗುವುದಿಲ್ಲ. ನಾವು ಮಾಡುವ ಕರ್ಮವನ್ನು ನಿಷ್ಠೆಯಿಂದ\nಭಗವದರ್ಪಣೆಯಾಗಿ ಮಾಡಿ, ಅದರಿಂದ ಏನು ಫಲ ಬಂತೋ ಅದನ್ನು ಹಾಗೇ ಸ್ವೀಕರಿಸುವ\nಮನೋವೃತ್ತಿಯನ್ನು ಬೆಳೆಸಿಕೊಂಡರೆ ದುಃಖವಿರುವುದಿಲ್ಲ.\n\nಯಾವ ಕಾಲಕ್ಕೂ ನಿಷ್ಕ್ರೀಯನಾಗಿ ಕುಳಿತುಕೊಳ್ಳದೇ ಸದಾ ಕರ್ತವ್ಯಶೀಲನಾಗು ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. \"ಹೀಗೇ\nಆಗಬೇಕು', “ಇಂತಹ ಫಲವೇ ಬರಬೇಕು' ಎನ್ನುವ ವಿಚಾರವನ್ನು ಬಿಟ್ಟು, ಕರ್ತವ್ಯ ನಿರ್ವಹಿಸಿದಾಗ ಯಾವ\nದುಃಖವೂ ಇಲ್ಲ. ಅದನ್ನು ಬಿಟ್ಟು ಫಲದಲ್ಲಿ ಅಧಿಕಾರ ಸಾಧಿಸಿದರೆ ಆ ಫಲ ದಕ್ಕದೇ ಇದ್ದಾಗ ಆಗುವ ಆಘಾತ,\nವ್ಯಾಕುಲತೆ ಭಯಾನಕ. ಸೋಲನ್ನಾಗಲೀ ಗೆಲುವನ್ನಾಗಲೀ ಸಮನಾಗಿ ಕಾಣುವ\nಮನಃಸ್ಥಿತಿ ನಮ್ಮನ್ನು ಎತ್ತರಕ್ಕೆ ಕೊಂಡೊಯ್ಯುತ್ತದೆ. ಈ ಹಿಂದೆ ಹೇಳಿದಂತೆ ನಾವು ಸೋಲಿನಲ್ಲಿ ಕಲಿತಷ್ಟು\nಗೆಲುವಿನಲ್ಲಿ. ಕಲಿಯಲಾಗದು. ಭಗವಂತ ನಮಗೆ ಫಲವನ್ನು ಕೊಡುವಾಗ ನಮ್ಮ ಒಳಿತನ್ನು\nಗಮನದಲ್ಲಿಟ್ಟುಕೊಂಡು ಕೊಡುತ್ತಾನೆಯೇ ಹೊರತು , ನಾವು ಅಂದುಕೊಂಡಂತೆ ಅಲ್ಲ. ಬಂದದ್ದನ್ನು ಬಂದಂತೆ\nಸ್ವೀಕರಿಸಿ, ಎಂದೂ ನಿಷ್ಕ್ರೀಯನಾಗದೇ, ಫಲದಲ್ಲಿ ಅಧಿಕಾರವನ್ನು ಸಾಧಿಸದೇ ಮುನ್ನೆಡೆಯಬೇಕು ಎನ್ನುವುದು\nಕೃಷ್ಣನ ಕರ್ಮಸಿದ್ಧಾಂತ. ಇಲ್ಲಿ ಅರ್ಜುನ ತಾನು ಧರ್ಮ ರಕ್ಷಣೆ ಮಾಡಲು, ಧರ್ಮದ ವಿಜಯಕ್ಕಾಗಿ ಯುದ್ಧ\nಮಾಡುತ್ತೇನೆ ಅಂದುಕೊಳ್ಳುವುದು ತಪ್ಪಲ್ಲ. ಈ ಹಂತದಲ್ಲಿ ಸೋಲು-ಗೆಲುವಿನ ಬಗ್ಗೆ ಯೋಚಿಸದೇ, ಅದನ್ನು\nಪೂರ್ಣ ಭಗವಂತನಲ್ಲಿ ಅರ್ಪಿಸಿ, ತನ್ನ ಪಾಲಿಗೆ ಬಂದ ಕರ್ತವ್ಯವನ್ನು ನಿಷ್ಟೆಯಿಂದ ತನ್ನ ಶಕ್ತಿ ಮೀರಿ\nನಿಭಾಯಿಸುವುದು ಆತನ ಧರ್ಮ. ಹೀಗೆ ಮಾಡಿದಾಗ ಯುದ್ಧದ ಪ್ರತಿಯೊಂದು ಹಂತದಲ್ಲಿ ಬರುವ ಫಲಿತಾಂಶ\nಆತನನ್ನು ಕಂಗೆಡಿಸಲಾರವು. ಏನೇ ಫಲಿತಾಂಶ ಬಂದರೂ ಅದು ಭಗವಂತನ ಪ್ರಸಾದ ಎಂದು ಸ್ವೀಕರಿಸುತ್ತಾ\nಮುಂದೆ ಸಾಗಬೇಕು ಅಷ್ಟೆ.",
  "2.48": "ಯೋಗಸ್ಥಃ ಕುರು ಕರ್ಮಾಣಿ ಸಂಗಮ್‌ ತ್ಯಕ್ತ್ವಾ ಧನಂಜಯ |\n\nಸಿದ್ಧಿ ಅಸಿದ್ಧ್ಯೋಃ ಸಮಃ ಭೂತ್ವಾ ಸಮತ್ವಂ ಯೋಗಃ ಉಚ್ಯತೇ - ಧನಂಜಯಾ, 'ಯೋಗ' ದಲ್ಲಿ ನೆಲೆಗೊಂಡು\nಕರ್ಮಗಳನ್ನು ಮಾಡು-ಫಲದ ನಂಟನ್ನು ತೊರೆದು, ಕೆಲಸ ಕೈಗೂಡಿದರೂ, ಕೆಟ್ಟರೂ-ಸಮಭಾವದಿಂದಿರು.\nಇಂತಹ ಸಮಭಾವಕ್ಕೆ 'ಯೋಗ'ವೆಂದು ಹೆಸರು.\n\nಎಂತಹ ಕರ್ಮ ಮಾಡುವುದಾದರೂ ಸಹ ಸುಮ್ಮನೆ ಮಾಡುವುದಲ್ಲ. ಅದರ ಹಿಂದೆ ಒಂದು ಯೋಗವಿರಬೇಕು.\nಭಗವಂತ ಫಲವನ್ನು ಕೊಡತಕ್ಕಂತವ, ನನ್ನಿಂದ ಕರ್ಮವನ್ನು ಮಾಡಿಸತಕ್ಕಂತವನೂ ಅವನೇ. ಏನು ಫಲ,\nಎಷ್ಟು ಫಲ, ಯಾವಾಗ ಫಲ, ಎಲ್ಲವೂ ಅವನಿಗೆ ಸೇರಿದ್ದು. ಸಿಕ್ಕಿದರೂ ಸಂತೋಷ, ಸಿಗದಿದ್ದರೂ ಸಂತೋಷ.\nಇದು ಭೌತಿಕ ಸಮತೋಲನ. ಇಂತಹ ಸಮತೋಲನದಲ್ಲಿ ಕರ್ತವ್ಯ ದೃಷ್ಟಿಯಿಂದ ಕರ್ಮವನ್ನು ಮಾಡಬೇಕು.\nನಮ್ಮ ಬದುಕಿನ ಸಮಸ್ತ ಕರ್ಮದಲ್ಲಿ ಈ ಅನುಸಂಧಾನವಿದ್ದಾಗ ಅದು ಭಗವಂತನ ಪೂಜೆಯಾಗುತ್ತದೆ. ಇದೇ\nಕರ್ಮಯೋಗ.\n\nಸಿದ್ಧಿ-ಅಸಿದ್ದಿಯನ್ನು ಸಮಭಾವದಿಂದ ಕಾಣುವುದು ಮನಸ್ಸಿನ ಯೋಗ. ಇದೊಂದು ಮಾನಸಿಕ ಸ್ಥಿತಿ. ಈ ರೀತಿಯ\nಯೋಗ ಭಾವನೆಯಿಂದ ಕರ್ಮ ಮಾಡಿದರೆ-ಫಲ ಬಂದಾಗ ಹೆಗ್ಗಳಿಕೆ ಇರುವುದಿಲ್ಲ, ಬಾರದೇ ಇದ್ದಾಗ\nದುಃಖವಿರುವುದಿಲ್ಲ. ಹೀಗೆ ಸಿದ್ಧಿ-ಅಸಿದ್ದಿಗಳ ಸಮತ್ವದಿಂದ ಮಾಡುವ ಪ್ರತಿಯೊಂದು ಕರ್ತವ್ಯವೂ ಕೂಡಾ\nಭಗವಂತನ ಪೂಜೆಯಾಗುತ್ತದೆ. ಈ ಅನುಸಂಧಾನವಿಲ್ಲದೆ ಮಾಡುವ ಮಹಾಯಜ್ಞ ಕೂಡಾ ಪೂಜೆ ಆಗಲಾರದು.\nಭಗವಂತ ನನ್ನಿಂದ ಈ ಕೆಲಸವನ್ನು ಮಾಡಿಸಿದ. ಇದು ಭಗವಂತನ ಪೂಜಾರೂಪವಾಗಿ ಅರ್ಪಿತವಾಗಲಿ ಎನ್ನುವ\nಅನುಸಂಧಾನವಿದ್ದಾಗ ಮಾತ್ರ ಕರ್ಮ-ಯೋಗವಾಗುತ್ತದೆ. ನಮ್ಮ ಮನಸ್ಸು ಭಗವಂತನಲ್ಲಿ ಸಂಯೋಗ\nಹೊಂದುವುದೇ ಯೋಗ. ಈ ಅನುಸಂಧಾನಕ್ಕೆ ಪೂರಕವಾದ ಮತ್ತು ಅನುಸಂಧಾನಪೂರ್ವಕವಾದ ಎಲ್ಲಾ\nಕರ್ಮವೂ ಕರ್ಮಯೋಗ.",
  "2.49": "ದೂರೇಣ ಹಿ ಅವರಮ್‌ ಕರ್ಮ ಬುದ್ಧಿಯೋಗಾತ್‌ ಧನಂಜಯ |\n\nಬುದ್ಧೌ ಶರಣಮ್‌ ಅನ್ವಿಚ್ಛ ಕೃಪಣಾಃ ಫಲಹೇತವಃ -- ಧನಂಜಯಾ, ಅರಿವಿನ ದಾರಿಗಿಂತ ಕರ್ಮದ ದಾರಿ ತುಂಬಾ\nಕೀಳು. ಅದರಿಂದ ಅರಿವಿನಲ್ಲಿ ನೆಲೆನಿಲ್ಲು.[ಅರಿವು ಬಂದ ಮೇಲೂ ಹರಿಗೆ ಶರಣಾಗು]. ಫಲವನ್ನೆ ೀ ನಂಬಿ\nನಿಂತವರು ಮರುಕಪಡಬೇಕಾದವರು.\n\nಪ್ರಪಂಚದಲ್ಲಿ ಕೆಲವರು ಕರ್ಮಯೋಗಿಗಳು, ಇನ್ನು ಕೆಲವರು ಜ್ಞಾನಯೋಗಿಗಳು. ಕರ್ಮಯೋಗಿಗಳಿಗೆ ಜ್ಞಾನವಿಲ್ಲ,\nಹಾಗೂ ಜ್ಞಾನ ಬಂದ ಮೇಲೆ ಕರ್ಮ ಬೇಕಿಲ್ಲ ಎನ್ನುವ ಚಿಂತನೆ ಕೆಲವರದು. ಕೆಲವರು ಕರ್ಮ ಮೇಲೆನ್ನುತ್ತಾರೆ\nಮತ್ತೆ ಕೆಲವರು ಜ್ಞಾನ ಮೇಲು ಎನ್ನುತ್ತಾರೆ. ಇನ್ನು ಕೆಲವರು ಕರ್ಮ ಮತ್ತು ಜ್ಞಾನ- “ಎರಡು ಚಕ್ರಗಳಂತೆ'\nಸಮಾನ ಎಂದು ವಾದ ಮಾಡುತ್ತಾರೆ. ಇದರಿಂದ ಅನೇಕ ದ್ವಂದ್ವಗಳು ಹುಟ್ಟಿಕೊಳ್ಳುತ್ತವೆ. ಆದರೆ ಕೃಷ್ಣ ಇಲ್ಲಿ\nಸ್ಪಷ್ಟವಾಗಿ ಹೇಳುತ್ತಾನೆ: ಜ್ಞಾನದ ಮುಂದೆ ಕರ್ಮ ಬಹಳ ದೂರ ಎಂದು. ಕರ್ಮ ಮಾಡುವಾಗ ಜ್ಞಾನ ಅತಿಮುಖ್ಯ.\nಜ್ಞಾನಕ್ಕೋಸ್ಕರ ಕರ್ಮವಿರುವುದೇ ಹೊರತು ಅದು ಜ್ಞಾನಕ್ಕೆ ಸಮಾನ ಅಲ್ಲ. ಅದಕ್ಕಾಗಿ ಜ್ಞಾನಕ್ಕೆ ಶರಣಾಗಿ\nಜ್ಞಾನಕ್ಕೆ ಪೂರಕವಾದ ಕರ್ಮ ಮಾಡಬೇಕು. ಜ್ಞಾನವಿಲ್ಲದೆ, ಫಲಾಪೇಕ್ಷೆಯಿಂದ ಕರ್ಮ ಮಾಡುವರ ಸ್ಥಿತಿ\nಶೋಚನೀಯ. ಇವರು ಕರ್ಮದ ಮರ್ಮವನ್ನು ತಿಳಿಯದೇ ಕರ್ಮ ಮಾಡಿ ಒದ್ದಾಡುತ್ತಿರುತ್ತಾರೆ.\n\nಜ್ಞಾನದ ಮಾರ್ಗದಲ್ಲಿ ಎತ್ತರಕ್ಕೇರಲು ಸಾವು ಕರ್ಮವನ್ನು ಮಾಡಬೇಕು. ಇದರಿಂದ ಭಗವಂತನ\nಸಾಕ್ಷಾತ್ಕಾರವಾಗುತ್ತದೆ. ಈ ಸ್ಥಿತಿಯಲ್ಲಿ ಅಹಂಕಾರ ಪಡದೆ, ಭಗವಂತನೇ ನನ್ನ ರಕ್ಷಕ ಹಾಗೂ ಆತನೇ ನನ್ನ\nನೆಲೆ ಎಂದು ತಿಳಿದು ಆತನಲ್ಲಿ ಶರಣಾಗಬೇಕು. ದೇವರಿಗೆ ನಾನು ನನ್ನನ್ನು ಅರ್ಪಿಸಿಕೊಂಡಿದ್ದೇನೆ, ಆತ ನನ್ನನ್ನು\nರಕ್ಷಿಸಿಯೇ ರಕ್ಷಿಸುತ್ತಾನೆ ಎನ್ನುವ ಮನವರಿಕೆ ಶರಣಾಗತಿ.\n\nನಮಗೆ ಏನಾದರೂ ಸಮಸ್ಯೆ ಬಂದಾಗ ಭಗವಂತನ ಹತ್ತಿರ ಪ್ರಾರ್ಥಿಸಿಕೊಳ್ಳಬೇಕೇ ಹೊರತು ಅನ್ಯರನ್ನಲ್ಲ. \"ಓ\nಭಗವಂತಾ, ನನ್ನನ್ನು ಏಕೆ ಈ ಸಮಸ್ಯೆಯಲ್ಲಿ ಸಿಲುಕಿಸಿದಿ? ಇದಕ್ಕೆ ಪರಿಹಾರವನ್ನು ತೋರಿಸು ತಂದೆ\" ಎಂದು\nಮನಃಪೂರ್ವಕವಾಗಿ ಕೇಳಿಕೊಂಡರೆ ಖಂಡಿತ ಆತ ನಮ್ಮನ್ನು ಸಂಕಟದಿಂದ ಪಾರು ಮಾಡುತ್ತಾನೆ. ಆದರೆ ಇಲ್ಲಿ\nಕೂಡಾ ಫಲದ ಅಧಿಕಾರ ಸಾಧಿಸದೆ, ಕೇವಲ ಭಗವಂತನನ್ನು ನಂಬಿ, ನಮ್ಮ ಎಲ್ಲಾ ಸಮಸ್ಯೆಗಳ ನಡುವೆಯೂ\nನಿಶ್ಚಿಂತೆಯಿಂದ ಬದುಕಲು ಕಲಿಯಬೇಕು.\n\nಮುಂದಿನ ಶ್ಲೋಕವನ್ನು ನೋಡುವ ಮೊದಲು ಇಲ್ಲಿ ಬಂದಿರುವ ಧನಂಜಯ ಎನ್ನುವ ನಾಮವಿಶೇಷಣದ\nಅರ್ಥವನ್ನು ತಿಳಿಯೋಣ. ಈ ಸಂಬೋಧನೆಗೆ ಎರಡು ಅರ್ಥವಿದೆ. ಒಂದು ಲೌಕಿಕ ಹಾಗೂ ಇನ್ನೊಂದು\nಆಧ್ಯಾತ್ಮಿಕ ಅರ್ಥ. ಲೌಕಿಕವಾಗಿ ನೋಡಿದರೆ ಅರ್ಜುನ ಅನೇಕ ಕಡೆ ಯುದ್ಧ ಮಾಡಿ, ದೇಶದ ಸೀಮೆಯನ್ನು\nವಿಸ್ತರಿಸಿ, ರಾಜಕೋಶದ ಸಂಪತ್ತನ್ನು ವೃದ್ಧಿ ಮಾಡಿದವ-ಆದ್ದರಿಂದ ಆತ ಧನಂಜಯ. ಆಧ್ಯಾತ್ಮಿಕವಾಗಿ\nನೋಡಿದರೆ ಈ ನಾಮಕ್ಕೆ ವಿಶೇಷ ಅರ್ಥವಿದೆ. ಭಗವಂತನ ಆರಾಧನೆ, ಅಧ್ಯಾತ್ಮದ ಅರಿವು-ನಿಜವಾದ ಧನ.\nಭಗವಂತನ ಅರಿವು, ಜ್ಞಾನ ಎಲ್ಲಕ್ಕಿಂತ ದೊಡ್ಡ ಸಂಪತ್ತು. ಅರ್ಜುನ ಆ ಕಾಲದ ಅಪರೋಕ್ಷ ಜ್ಞಾನಿ. ಆತ ಸ್ವಯಂ\nಇಂದ್ರ. ಆತ ಜ್ಞಾನದ ಸಂಪತ್ತಿನ ಪರಾಕಾಷ್ಠೆ. 'ಇಂತಹ ಜ್ಞಾನಿಯಾದ ನೀನು ಭಗವಂತನಿಗೆ ಶರಣಾಗಿ,\nಬುದ್ಧಿಪೂರ್ವಕವಾಗಿ ಕರ್ಮಮಾಡು' ಎನ್ನುವ ಅರ್ಥದಲ್ಲಿ ಕೃಷ್ಣ ಈ ಸಂಬೋಧನೆ ಮಾಡಿದ್ದಾನೆ.\n",
  "2.50": "ಬುದ್ಧಿಯುಕ್ತಃ ಜಹಾತಿ ಇಹ ಉಭೇ ಸುಕೃತದುಷ್ಕೃತೇ |\n\nತಸ್ಮಾತ್‌ ಯೋಗಾಯ ಯುಜ್ಯಸ್ವ ಯೋಗಃ ಕರ್ಮಸು ಕೌಶಲಮ್‌- ಭಗವಂತನನ್ನರಿತವನು ಬೇಡವಾದ\nಪುಣ್ಯಪಾಪಗಳೆರಡನ್ನೂ ಇಲ್ಲೇ ತೊರೆಯುತ್ತಾನೆ. ಆದ್ದರಿಂದ ಅರಿವಿನ 'ಯೋಗ'ಕ್ಕೆ ತೊಡಗು. 'ಯೋಗ'ವೆಂದರೆ\nಇದೇ: ತಿಳಿದು ಮಾಡುವ ಜಾಣತನ.\n\nತಿಳುವಳಿಕೆಯಿಂದ ಕರ್ಮ ಮಾಡಿದರೆ ತನ್ನ ಎಲ್ಲಾ ಪಾಪಗಳನ್ನು ಹಾಗೂ ಬೇಡವಾದ ಪುಣ್ಯವನ್ನು ತೊರೆದು\nಭಗವಂತನನ್ನು ಸೇರುತ್ತಾನೆ. ಇಲ್ಲಿ ಬೇಡವಾದ ಪುಣ್ಯ ಅಂದರೆ: ಉದಾಹರಣೆಗೆ ಒಬ್ಬ ಮಹಾತ್ಮ ತನ್ನ ಜ್ಞಾನ\nಕರ್ಮಗಳಿಂದ ಮೋಕ್ಷವನ್ನು ಪಡೆಯುತ್ತಾನೆ. ಹೀಗೆ ಈ ಮಾರ್ಗದಲ್ಲಿರುವಾಗ ಆತ ಇತರ ಪುಣ್ಯವನ್ನೂ\nಗಳಿಸುತ್ತಾನೆ. ಒಂದು ವೇಳೆ ಆತ ಚಕ್ರವರ್ತಿಯಾಗಿ ಮೆರೆಯುವ ಪುಣ್ಯವನ್ನು ಪಡೆದಿದ್ದರೆ ಅದು ಆತನಿಗೆ\nಬೇಡವಾದ ಪುಣ್ಯ. ಏಕೆಂದರೆ ಮೋಕ್ಷದ ಮುಂದೆ ಈ ಪುಣ್ಯದ ಅವಶ್ಯಕತೆ ಆತನಿಗಿಲ್ಲ. ಆತ ಈ ಪುಣ್ಯವನ್ನು ಇಲ್ಲೇ\n\nತೊರೆಯುತ್ತಾನೆ. ಇದನ್ನು ಇಲ್ಲಿ ಬೇಡವಾದ ಪುಣ್ಯ ಎಂದಿರುವುದು. ಯಾರು ಹೀಗೆ ಭಗವತ್ವ್ರ್ರಜ್ಞೆಯಲ್ಲಿ\nಬದುಕುತ್ತಾರೋ ಅವರು ಮಾಡಿದ ಕರ್ಮ ಅವರ ಪಾಪ ಪುಣ್ಯದ ಬಂಧನಕ್ಕೆ ಕಾರಣವಾಗುವುದಿಲ್ಲ. ಆದ್ದರಿಂದ\nಜ್ಞಾನಯೋಗದಲ್ಲಿ ನಿಂತು ಆ ಅರಿವಿನಿಂದ ಕರ್ಮವನ್ನು ಮಾಡುವುದು ಜಾಣತನ.\n",
  "2.51": "ಕರ್ಮಜಮ್‌ ಬುದ್ಧಿಯುಕ್ತಾಃ ಹಿ ಫಲಮ್‌ ತ್ಯಕ್ತ್ವಾ ಮನೀಷಿಣಃ |\n\nಜನ್ಮಬಂಧ ವಿನಿರ್ಮುಕ್ತಾಃ ಪದಮ್‌ ಗಚ್ಛಂತಿ ಅನಾಮಯಮ್‌ --ಬಲ್ಲವರು ಭಗವಂತನ ಅರಿವು ಪಡೆದು, ಕರ್ಮ\nಫಲದ ಹೊಣೆಯನ್ನು ಅವನಿಗೊಪ್ಪಿಸಿ, ಹುಟ್ಟು ಸಾವಿನ ಕಟ್ಟು ಕಳಚಿಕೊಂಡು, ಕ್ಲೇಶರಹಿತವಾದ ಪದವನ್ನು\nಪಡೆಯುತ್ತಾರೆ.\n\nನಿಜವಾದ ಮನಿಷಿಗಳು ತಮ್ಮ ಮನಸ್ಸನ್ನು ತಾವೇ ನಿಯಂತ್ರಿಸಿಕೊಳ್ಳಬಲ್ಲ ಜಿತೇಂದ್ರಿಯರು. ಆತ್ಮಸಂಯಮ\nಇರುವ ಜ್ಞಾನದ ಮಾರ್ಗದಲ್ಲಿ ಸಾಗಿ ಆ ಅರಿವನ್ನು ಪಡೆದವರು. ಬುದ್ಧಿವಂತರಾದ ಜ್ಞಾನಿಗಳು ಕರ್ಮದಿಂದ\nಬರತಕ್ಕಂತಹ ಫಲದ ಮೋಹವನ್ನುಬಿಟ್ಟು ಅದನ್ನು ಭಗವಂತನಿಗೆ ಅರ್ಪಿಸುತ್ತಾರೆ. ಹೀಗೆ ಯಾರು\nಕರ್ಮ ಫಲವನ್ನು ಭಗವಂತನಿಗೆ ಅರ್ಪಣ ಬುದ್ಧಿಯಿಂದ ತ್ಯಾಗ ಮಾಡಿ ನಿರ್ವಂಚನೆಯಿಂದ ಕರ್ಮ\nಮಾಡುತ್ತಾರೊ, ಅವರು. ಕರ್ಮ ಮಾಡಿದರೂ ಕರ್ಮಬಂಧನಕ್ಕೊಳಪಡದೇ, ಎಲ್ಲಾ ಬಂಧನವನ್ನು\nಕಳಚಿಕೊಂಡು, ದೋಷ ರಹಿತವಾದ ಮೋಕ್ಷವನ್ನು ಪಡೆಯುತ್ತಾರೆ. ಆದ್ದರಿಂದ ಕರ್ತವ್ಯ ಕರ್ಮವನ್ನು ಭಗವಂತನ\nಆರಾಧನೆ ಎಂದು ಮಾಡಿ ಮೋಕ್ಷ ಪಡೆಯಬೇಕು. ಇದನ್ನು ಹೊರತುಪಡಿಸಿ. “ನಾನು ಜ್ಞಾನಿ, ನಾನೇನೂ\nಮಾಡಲಾರೆ' ಎನ್ನುವ ಧೋರಣೆ ಸರಿಯಲ್ಲ.",
  "2.52": "ಯದಾ ತೇ ಮೋಹ ಕಲಿಲಮ್‌ ಬುದ್ಧಿಃ ವ್ಯತಿತರಿಷ್ಯತಿ ।\nತದಾ ಗಂತಾ ಅಸಿ ನಿರ್ವೇದಮ್‌ ಶ್ರೋತವ್ಯಸ್ಯ ಶ್ರುತಸ್ಯ ಚ --ಎಂದು ನಿನ್ನ ಬುದ್ಧಿ ಅಜ್ಞಾನದ ಕೊಳೆಯನ್ನು ಕಳೆದುಕೊಳ್ಳುವುದೋ, ಅಂದು ಮುಂದೆ ಕೇಳುವ, ಹಿಂದೆ ಕೇಳಿದ ಉಪದೇಶದ ಪೂರ್ತಿ ಫಲವನ್ನು ಪಡೆಯುವೆ.\n\nಯಾವಾಗ ನಾವು ಓದಿದ್ದು ಕೇಳಿದ್ದು ಸಾರ್ಥಕವಾಗುವುದು? ನಮ್ಮ ಬುದ್ಧಿ ಎಷ್ಟು ಕೇಳಿದರೂ ಕೂಡಾ ಪುನಃ ಗೊಂದಲದಲ್ಲೇ ಇದ್ದರೆ-ಎಷ್ಟು ಕೇಳಿಯೂ ಉಪಯೋಗವಿಲ್ಲ. ಓದುವುದರಿಂದ, ಕೇಳುವುದರಿಂದ ನಮ್ಮ ಮನಸ್ಸಿನ ಕೊಳೆ ತೊಳೆದು ಹೋಗಿ ಮನಸ್ಸು ತಿಳಿಯಾಗಬೇಕು.",
  "2.53": "ಶ್ರುತಿ ವಿಪ್ರತಿಪನ್ನಾ ತೇ ಯದಾ ಸ್ಥಾಸ್ಯತಿ ನಿಶ್ಚಲಾ |\n\nಸಮಾಧೌ ಅಚಲಾ ಬುದ್ಧಿಃ ತದಾ ಯೋಗಮ್‌ ಅವಾಪ್ಟ್ಯಸಿ- ಮೊದಲು ಶ್ರುತಿಗಳಿಗೆ ಹೊಂದಿಕೊಳ್ಳದಿದ್ದ,[ಮತ್ತೆ\nಶ್ರುತಿಗಳಿಂದ ಶ್ರುತಿಗೂಡಿದ,] ನಿನ್ನ ಬುದ್ಧಿ ಎಂದು ನಿಜದ ಅರಿವಿನಿಂದ ಗಟ್ಟಿಗೊಂಡು, ಸಮಾಧಿಯಲ್ಲಿ ನಲುಗದೇ\nನಿಲ್ಲುವುದೋ, ಅಂದು ಗುರಿ ತಲುಪುವೆ.\n\nಇಲ್ಲಿ 'ವಿಪ್ರತಿಪನ್ನಾ' ಅಂದರೆ 'ಅಭಿಪ್ರಾಯಭೇದ'. ಮೊದಲು ಶ್ರುತಿಗಳಿಂದ (ಶ್ರವಣದಿಂದ) ಗೊಂದಲವೆನಿಸುತ್ತದೆ.\nನಂತರ ಅಲ್ಲಿಂದ ವೇದಕ್ಕೆ ಹೋದಾಗ-ವೇದದಲ್ಲಿ ಹೇಳಿದ ಸಂಗತಿಗೆ ಮನಸ್ಸು ವಿರುದ್ಧವಾಗಿ ಯೋಚಿಸುತ್ತದೆ.\nಆದರೆ ಒಮ್ಮೆ ಮನಸ್ಸು ತಿಳಿಯಾದಾಗ, ಶ್ರುತಿಯಲ್ಲಿ ಹೇಳಿದ ತ್ರಿಗುಣಾತೀತ ತತ್ವದಲ್ಲಿ ಮನಸ್ಸು ಗಟ್ಟಿಯಾಗಿ\nಕುಳಿತುಕೊಳ್ಳುತ್ತದೆ. ಮೊದಲು ತ್ರೈಗುಣ್ಯ ವಿಷವಾಗಿದ್ದು ನಂತರ ತ್ರೈಗುಣ್ಯದ ವಿಷವನ್ನು ಪರಿಹರಿಸುವಂತಾಗುತ್ತದೆ\n(ಯಾಪಯತಿ). ಒಮ್ಮೆ ಮನಸ್ಸು ನಿರ್ಮಲವಾದಾಗ ಅದು ವೇದಕ್ಕೆ ಶ್ರುತಿಗೂಡು(Tune)ತ್ತದೆ. ಅದರಿಂದಾಗಿ\nವೇದದಲ್ಲಿ ಹೇಳಿರುವ ವಿಚಾರ ಮತ್ತು ನಮ್ಮ ಯೋಚನೆಗಳಲ್ಲಿ ಯಾವುದೇ ವ್ಯತ್ಯಾಸ ಕಾಣುವುದಿಲ್ಲ. ಮನಸ್ಸು\nವೈದಿಕ ವಾಜ್ಮಯದಲ್ಲಿ ನೆಲೆ ನಿಲ್ಲುತ್ತದೆ. ಈ ಸ್ಥಿತಿಯಲ್ಲಿ ಧ್ಯಾನ(Meditation) ಮಾಡಿದರೆ ಮನಸ್ಸು ಸದಾ\nಭಗವಂತನಲ್ಲಿ ನೆಲೆಗೊಳ್ಳುತ್ತದೆ. ಇದಕ್ಕೂ ಮುಂದೆ ಹೋಗಿ ನಿಶ್ಚಲವಾದ ಸಮಾಧಿ ಸ್ಥಿತಿಯಲ್ಲಿ, ಸ್ವರೂಪ\nಚಿಂತನದಲ್ಲಿ ನೋಡಿದಾಗ- ಭಗವಂತನ ನಿಜವಾದ ರೂಪ ಸಾಕ್ಷಾತ್ಕಾರವಾಗುತ್ತದೆ. ಈ ಸ್ಥಿತಿಯಲ್ಲಿ ಮನಸ್ಸು\nಕೆಲಸ ಮಾಡುವುದಿಲ್ಲ-ಆತ್ಮ ಕೆಲಸ ಮಾಡುತ್ತಿರುತ್ತದೆ. ಆತ್ಮದ ಕಣ್ಣಿನಿಂದ ಭಗವಂತನ ಸಾಕ್ಷಾತ್ಕಾರವಾಗುತ್ತದೆ-\nಇದು ಸಾಧನೆಯ ಪೂರ್ಣ ಫಲ.",
  "2.54": "ಸ್ಯ\nತಥೀಃ ಕಿಂ\n\nಪಿಂ ಪ್ರಿಂ\n\nಅರ್ಜುನಃ ಉವಾಚ -ಅರ್ಜುನ ಕೇಳಿದನು:\n\nತಪ್ರಜ್ಞಸ್ಯ ಕಾ ಭಾಷಾ ಸಮಾಧಿಸ್ಥಸ್ಯ ಕೇಶವ |\n\nತಧೀಃ ಕಿಮ್‌ ಪ್ರಭಾಷೇತ ಕಿಮ್‌ ಆಸೀತ ವ್ರಜೇತ ಕಿಮ್‌... ಓ ಬ್ರಹ್ಮರುದ್ರರ ನಿಯಾಮಕನೇ,\nರಮಾಧಿಯನ್ನೇರಬಲ್ಲ . ಆತ ಇಂತಹ ಎಲ್ಲಾ ಕ್ಷುದ್ರ ಕಾಮನೆಗಳನ್ನು\nತೊರೆದು... ತನ್ನೊಳಗಿರುವ ಜ್ಞಾನಾನಂದಮಯನಾದ ಭಗವಂತನನ್ನು ಕಾಣುತ್ತಾ. ಸದಾ\n\nಸಂತೋಷವಾಗಿರುತ್ತಾನೆ.\n\nಮನುಷ್ಯನ ದುಃಖಕ್ಕೆ ಮೂಲ ಕಾರಣ ಆತನ ಕ್ಷುದ್ರ ಬಯಕೆಗಳು. ತನ್ನ ಬಯಕೆ ಈಡೇರದೇ ಇದ್ದಾಗ ದುಃಖ-\nಕೋಪ ಇತ್ಯಾದಿ ಆರಂಭವಾಗುತ್ತದೆ. ಇದರಿಂದ ಆತ ತನ್ನ ಜೀವನವನ್ನು ನರಕವನ್ನಾಗಿ ಮಾಡಿಕೊಳ್ಳುತ್ತಾನೆ.\nಇಂತಹ ಸ್ಥಿತಿಯಲ್ಲಿ ಆತನಿಗೆ ತನ್ನೊಳಗಿರುವ ಆ ಅಪೂರ್ವ ಶಕ್ತಿಯ ಬಗ್ಗೆ ಅರಿವಿರುವುದಿಲ್ಲ. ಸ್ಥಿತಪ್ರಜ್ಞನಾದವನು\nಈ ಜಂಜಾಟದಲ್ಲಿ ಸಿಲುಕದೇ, ತನ್ನಂತರಂಗದಲ್ಲಿನ ಆ ಮಹದಾನಂದವನ್ನು ಸದಾ ಸವಿಯುತ್ತಾ\nಸಂತೋಷವಾಗಿರುತ್ತಾನೆ. ಆತ ಕಾಮನೆಗಳಿಗೆ ಬೆಂಬೀಳುವುದಿಲ್ಲ. ಬೇಕು ಎನ್ನು ವ ಬಯಕೆ ಆತನನ್ನು\nಕಾಡುವುದಿಲ್ಲ. ಆತನ ಮನಸ್ಸು ಸದಾ ಪ್ರಸನ್ನವಾಗಿರುತ್ತದೆ. ಜೀವನದಲ್ಲಿ ಎಂತಹ ಸಮಸ್ಯೆ ಬಂದರೂ ಆತ\nಎಂದೂ ಉದ್ವೇಗಕ್ಕೆ (Tension or Stress) ಒಳಗಾಗುವುದಿಲ್ಲ. ಆತನ ಮನಸ್ಸು ಗಟ್ಟಿಯಾಗಿರುತ್ತದೆ ಮತ್ತು\nಇದರಿಂದಾಗಿ ಆತ ಯಶಸ್ಸನ್ನು ಕಾಣಬಲ್ಲ.\n\nಇಲ್ಲಿ ಕೃಷ್ಣ ಅರ್ಜುನನನ್ನು 'ಪಾರ್ಥ' ಎಂದು ಸಂಬೋಧಿಸಿದ್ದಾನೆ. ಪಾರ್ಥ ಎಂದರೆ ಪಾರ-ತೀರ-ಗಮನೆ, ಅಂದರೆ\nಸತ್ಯದ, ಸಾಧನೆಯ ಕಡಲನ್ನು ದಾಟಿದವ. “ಸಾಧನೆಯ ಕಡಲನ್ನು ದಾಟಿದ ನಿನಗೆ ಇದು ಸ್ಪಷ್ಟವಾಗಿ\nತಿಳಿಯಬೇಕು” ಎನ್ನುವ ಅರ್ಥದಲ್ಲಿ ಇಲ್ಲಿ ಈ ಸಂಬೋಧನೆ ಇದೆ.\n\nಮುಂದೆ ಬರುವ ಮೂರು ಶ್ಲೋಕಗಳಲ್ಲಿ ಕೃಷ್ಣ ಕಾಮನೆಗಳನ್ನು ಬಿಡುವುದು ಅಂದರೆ ಏನು ಹಾಗೂ ಹೇಗೆ?\nಎನ್ನುವುದನ್ನು ವಿವರಿಸುತ್ತಾನೆ.",
  "2.55": "ಪ್ರಜಹಾತಿ ಯದಾ ಕಾಮಾನ್ ಸರ್ವಾನ್ ಪಾರ್ಥ ಮನಃಗತಾನ್ |\nಆತ್ಮನಿ ಏವ ಆತ್ಮನಾ ತುಷ್ಟಃ ಸ್ಥಿತಪ್ರಜ್ಞಃ ತದಾ ಉಚ್ಯತೇ -- ಪಾರ್ಥಾ, ಮನದಲ್ಲಿ ಮನೆಮಾಡಿದ ಎಲ್ಲಾ ಬಯಕೆಗಳನ್ನು ತೊರೆದಾಗ, ಪರಮಾತ್ಮನಲ್ಲೇ ನೆಲೆನಿಂತು, ಪರಮಾತ್ಮನ ಹಸಾದದಿಂದ ತಣಿದು ನಲಿದಾಗ ಸ್ಥಿತಪ್ರಜ್ಞ ಎನಿಸುತ್ತಾನೆ.\n\nಕೃಷ್ಣ ನೇರವಾಗಿ ಸ್ಥಿತಪ್ರಜ್ಞನ ನಡೆ-ನುಡಿಗಳ ಬಗ್ಗೆ ಹೇಳದೇ, ಆತ ಹೇಗಿರುತ್ತಾನೆ ಎನ್ನುವುದನ್ನು ಇಲ್ಲಿ ಮೊದಲು ವಿವರಿಸುತ್ತಾನೆ. ನಿಜವಾದ ಸ್ಥಿತಪ್ರಜ್ಞನಿಗೆ ಮೂಲಭೂತವಾಗಿ ಯಾವ ಬಯಕೆಯೂ ಕಾಡುವುದಿಲ್ಲ (ಇಲ್ಲಿ ಬಯಕೆ ಎಂದರೆ ಮನುಷ್ಯನನ್ನು ದಾರಿ ತಪ್ಪಿಸುವ ಕೆಟ್ಟ ಕಾಮನೆಗಳು). ಆತ ಇಂತಹ ಎಲ್ಲಾ ಕ್ಷುದ್ರ ಕಾಮನೆಗಳನ್ನು ತೊರೆದು ತನ್ನೊಳಗಿರುವ ಜ್ಞಾನಾನಂದಮಯನಾದ ಭಗವಂತನನ್ನು ಕಾಣುತ್ತಾ ಸದಾ ಸಂತೋಷವಾಗಿರುತ್ತಾನೆ.",
  "2.56": "ದುಃಖೇಷು ಅನುದ್ವಿಗ್ನಮನಾಃ ಸುಖೇಷು ವಿಗತಸ್ಪೃಹಃ ।\nವೀತ ರಾಗ ಭಯ ಕ್ರೋಧಃ ಸ್ಥಿತಧೀ ಮುನಿಃ ಉಚ್ಯತೇ --ಸಂಕಟ ಬಂದಾಗ ಬಗೆಯಲ್ಲಿ ತಳಮಳವಿಲ್ಲ. ಸುಖದ ಸಂಗತಿಗಳಲ್ಲಿ ಹಂಬಲವಿಲ್ಲ. ಯಾವುದರಲ್ಲೂ ರಾಗವಿಲ್ಲ, ಭಯವಿಲ್ಲ, ಕ್ರೋಧವಿಲ್ಲ. ಇಂತಹ ಚಿಂತನಶೀಲ ‘ಸ್ಥಿತಪ್ರಜ್ಞ’ ಎನಿಸುತ್ತಾನೆ.\n\nಜೀವನದಲ್ಲಿ ಸುಖ-ದುಃಖಗಳು ಹಗಲು-ರಾತ್ರಿ ಇದ್ದಂತೆ. ಇದು ನಿರಂತರ ಮತ್ತು ಯಾರನ್ನೂ ಬಿಟ್ಟಲ್ಲ.",
  "2.57": "ಯಃ ಸರ್ವತ್ರ ಅನಭಿಸ್ನೇಹಃ ತತ್ ತತ್ ಪ್ರಾಪ್ಯ ಶುಭ ಅಶುಭಮ್ |\nನ ಅಭಿನಂದತಿ ನ ದ್ವೇಷ್ಟಿ ತಸ್ಯ ಪ್ರಜ್ಞಾ ಪ್ರತಿಷ್ಠಿತಾ -- ಆಯಾ ಒಳಿತು-ಕೆಡುಕುಗಳು ಬಂದೊದಗಿದಾಗ ಎಲ್ಲೂ ಅತಿಯಾಗಿ ಅಂಟಿಕೊಳ್ಳುವುದಿಲ್ಲ. ಒಳಿತಿನ ಬಗೆಗೆ ಮೆಚ್ಚು ಇಲ್ಲ. ಕೆಡುಕಿನ ಬಗ್ಗೆ ರೊಚ್ಚು ಇಲ್ಲ. ಇಂತವನ ಅರಿವು ಗಟ್ಟಿಗೊಂಡಿರುತ್ತದೆ.\n\nಇಲ್ಲಿ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ - \"ದುಃಖ ಬಂದಾಗ ಕಂಗೆಡಬೇಡ, ಸುಖ ಬಂದಾಗ ಉಬ್ಬಬೇಡ, ನಿರ್ಲಿಪ್ತತೆಯನ್ನು ಅಭ್ಯಾಸ ಮಾಡು. ಯಾವುದರ ಮೇಲೂ ಅತಿಯಾದ ಆಸಕ್ತಿ (Over attachment) ಬೇಡ. ಮನಸ್ಸಿನ ಸಮತೋಲನವನ್ನು ಸಾಧಿಸು\" ಎಂದು.",
  "2.58": "ಯದಾ ಸಂಹರತೇ ಚ ಅಯಮ್‌ ಕೂರ್ಮಃ ಅಂಗಾನಿ ಇವ ಸರ್ವಶಃ ।\nಇಂದ್ರಿಯಾಣಿ ಇಂದ್ರಿಯ ಅರ್ಥೇಭ್ಯಃ ತಸ್ಯ ಪ್ರಜ್ಞಾ ಪ್ರತಿಷ್ಠಿತಾ-- ಹೇಗೆ ಆಮೆಯು ತನ್ನ ಅಂಗಗಳನ್ನು ಪೂರ್ತಿಯಾಗಿ ಚಿಪ್ಪಿನೊಳಗೆ ಎಳೆದುಕೊಳ್ಳುತ್ತದೋ ಹಾಗೇ, ಇಂದ್ರಿಯಗಳನ್ನು ಇಂದ್ರಿಯ ವಿಷಯಗಳಿಂದ ಹಿಂದಕ್ಕೆ ಎಳೆದುಕೊಳ್ಳುವವರ ಪ್ರಜ್ಞೆ ಗಟ್ಟಿಗೊಂಡಿರುತ್ತದೆ.",
  "2.59": "ವಿಷಯಾಃ ವಿನಿವರ್ತಂತೇ ನಿರಾಹಾರಸ್ಯ ದೇಹಿನಃ |\n\nರಸವರ್ಜಮ್‌ ರಸಃ ಅಪಿ ಅಸ್ಯ ಪರಮ್‌ ದೃಷ್ಟ್ವಾ ನಿವರ್ತತೇ- -ಆಹಾರ ತೊರೆದ ಜೀವಿಗೆ ವಿಷಯ ಭೋಗದ\nಕಸುವಷ್ಟೇ ಕುಂದುತ್ತದೆ-ನಾಲಗೆಯ ಕಸು ಮತ್ತು ಭೋಗದ ಬಯಕೆಯನ್ನು ಬಿಟ್ಟು. ಅಂತಹ ಕಸುವು-ಬಯಕೆ\nಕೂಡಾ ಭಗವಂತನನ್ನು ಕಂಡಾಗ ಇಲ್ಲವಾಗುತ್ತದೆ.\n\nನಾವು ಸ್ಥಿತಪ್ರಜ್ಞರಾಗಬೇಕೆಂದರೆ ಇಂದ್ರಿಯಗಳನ್ನು ಅಂತರ್ಮುಖಗೊಳಿಸಬೇಕು ಎನ್ನುವ ವಿಷಯವನ್ನು\nನೋಡಿದೆವು. ಆದರೆ ಅದು ಅಷ್ಟು ಸುಲಭದ ವಿಷಯವಲ್ಲ. ಸಾಧನಾ ಶರೀರದಲ್ಲಿರುವ ಸಾಧಕ, ಇಂದ್ರಿಯಗಳನ್ನು\nಹೊರಗಿನ ವಿಷಯಗಳ ಜೊತೆಗೆ ಸಂಪರ್ಕ ಆಗದಂತೆ ತಡೆದರೆ(ಏಕಾಂತದ ಅಭ್ಯಾಸ), ನೋಡುವ, ಕೇಳುವ\nಎಲ್ಲಾ ಆಸೆಗಳು ಹೊರಟು ಹೋಗಬಹುದು. ಆದರೆ ರುಚಿ(ನಾಲಿಗೆಯ ಚಪಲ) ಮತ್ತು ಶೃಂಗಾರ(ಲೈಂಗಿಕ\nಬಯಕೆ)ವನ್ನು ನಿವಾರಿಸುವುದು ಬಹಳ ಕಷ್ಟ. ಈ ಕಾರಣಕ್ಕಾಗಿ ನಾವು ಬ್ರಹ್ಮಚರ್ಯ ಪಾಲನೆ\nಮಾಡಬೇಕೆಂದಿದ್ದರೆ ಒಮ್ಮೆ ಶೃಂಗಾರ ಭೋಗವನ್ನು ಅನುಭವಿಸಿ, ದಾಂಪತ್ಯವೆಂದರೆ ಏನು ಎಂದು ಅರಿತು,\nಆನಂತರ ಬ್ರಹ್ಮಚರ್ಯಕ್ಕೆ ಕಾಲಿಟ್ಟರೆ ಸಾಧನೆ ಸುಲಭ. ನಿಯಮಿತ ಆಹಾರ, ಉಪವಾಸ- ಅಧ್ಯಾತ್ಮಕ್ಕೆ\nಪೂರಕ. ಅತಿ ಆಹಾರ, ತಾಮಸ ಹಾಗೂ ರಾಜಸ ಅಹಾರ (ಉದಾ: ತೊಗರಿಬೇಳೆ, ಈರುಳ್ಳಿ, ಬೆಳ್ಳುಳ್ಳಿ,\nನುಗ್ಗೆಕಾಯಿ, ಅತಿಯಾದ ಮಸಾಲೆ ಪದಾರ್ಥ, ಮಾಂಸಾಹಾರ ಇತ್ಯಾದಿ) ಅಧ್ಯಾತ್ಮ ಸಾಧನೆಗೆ ತೀರಾ ವಿರುದ್ಧ.\n(ಈ ಕಾರಣಕ್ಕಾಗಿ ಯಾರೇ ಅತಿಥಿ ಬಂದಾಗ ಅವರಿಗೆ ಒತ್ತಾಯ ಪೂರ್ವಕವಾಗಿ ಆಹಾರ ನೀಡಬಾರದು;\nಮಾಡಿದ ಅಡಿಗೆ ಮಿಕ್ಕಿದಾಗ ಹಾಳಾಗುತ್ತಲ್ಲಾ ಅಂತ ತಿನ್ನು ವುದರಿಂದ ಆಹಾರವೂ ಹಾಳು ದೇಹವೂ ಹಾಳು! ).\nಒಟ್ಟಿನಲ್ಲಿ ಅಧ್ಯಾತ್ಮ ಸಾಧನೆಯಲ್ಲಿ ಏಕಾಂತ ಹಾಗೂ ಆಹಾರ ನಿಯಂತ್ರಣ ಸಾಧನೆಗೆ ಪೂರಕ . ಇದರಿಂದ\nನಮ್ಮ ನಾಲಿಗೆಯ ಮತ್ತು ಭೋಗದ ಚಪಲ ಸಂಪೂರ್ಣ ನಿಗ್ರಹ ಆಗದಿದ್ದರೂ ಕೂಡಾ ಅವು ಭಗವಂತನಲ್ಲಿ\nಸಂಪೂರ್ಣ ಶರಣಾದಾಗ ಇಲ್ಲವಾಗುತ್ತವೆ.",
  "2.60": "ಯತತಃ ಹಿ ಅಪಿ ಕೌಂತೇಯ ಪುರುಷಸ್ಯ ವಿಪಶ್ಚಿತಃ |\nಇಂದ್ರಿಯಾಣಿ ಪ್ರಮಾಧೀನಿ ಹರಂತಿ ಪ್ರಸಭಮ್ ಮನಃ -- ಸಾಧಕ ಸಾಕಷ್ಟು ತಿಳಿದುಕೊಂಡರೂ, ಸಾಕಷ್ಟು ಪ್ರಯತ್ನಿಸಿದರೂ ಕೂಡಾ, ಇಂದ್ರಿಯಗಳು ಬಲವಂತವಾಗಿ ಮನಸ್ಸನ್ನು ಕಲಕಿ ಸೆಳೆದುಬಿಡುತ್ತವೆ.",
  "2.61": "ತಾನಿ ಸರ್ವಾಣಿ ಸಂಯಮ್ಯ ಯುಕ್ತಃ ಆಸೀತ ಮತ್‌ ಪರಃ ।\nವಶೇ ಹಿ ಯಸ್ಯ ಇಂದ್ರಿಯಾಣಿ ತಸ್ಯ ಪ್ರಜ್ಞಾ ಪ್ರತಿಷ್ಠಿತಾ -- ಅವುಗಳನ್ನೆಲ್ಲಾ ತಡೆಹಿಡಿದು, ನನ್ನನ್ನೇ ಪರತತ್ತ್ವವೆಂದು ನಂಬಿ ನನ್ನಲ್ಲೇ ಮನವಿಟ್ಟು ಕೂಡಬೇಕು. ಹೀಗೆ ಇಂದ್ರಿಯಗಳನ್ನು ಗೆದ್ದವನ ಅರಿವು ಗಟ್ಟಿಗೊಂಡಿರುತ್ತದೆ.",
  "2.62": "ಧ್ಯಾಯತಃ ವಿಷಯಾನ್‌ ಪುಂಸಃ ಸಂಗಃ ತೇಷು ಉಪಜಾಯತೇ |\n\nಸಂಗಾತ್‌ ಸಂಜಾಯತೇ ಕಾಮಃ ಕಾಮಾತ್‌ ಕ್ರೋಧಃ ಅಭಿಜಾಯತೇ -- ವಿಷಯಗಳನ್ನೇ ನೆನೆಯುತ್ತಿರುವ\nಮನುಷ್ಯನಿಗೆ ಅವುಗಳ ನಂಟು ಬೆಳೆಯುತ್ತದೆ. ನಂಟಿನಿಂದ ಆಸೆ ಕುದುರುತ್ತದೆ. ಆಸೆಗೆ ಅಡ್ಡಿಯಾದಾಗ ರೊಚ್ಚು\nಮೂಡುತ್ತದೆ.",
  "2.63": "ಕ್ರೋಧಾತ್‌ ಭವತಿ ಸಮ್ಮೋಹಃ ಸಮ್ಮೋಹಾತ್‌ ಸ್ಮೃತಿ ವಿಭ್ರಮಃ |\n\nಸ್ಮೃತಿಭ್ರಂಶಾತ್‌ ಬುದ್ಧಿನಾಶಃ ಬುದ್ಧಿನಾಶಾತ್‌ ವಿನಶ್ಯತಿ --ರೊಚ್ಚಿನಿಂದ ಮಾಡಬಾರದ್ದನ್ನು ಮಾಡುವ ಬಯಕೆ\n(ತಪ್ಪು ಗ್ರಹಿಕೆ). ಅಂತಹ ಬಯಕೆಗಳಿಂದ ವಿಧಿ-ನಿಷೇಧಗಳ ಮರೆವು. ಮರೆವಿನಿಂದ ತಿಳಿಗೇಡಿತನ,\nತಿಳಿಗೇಡಿತನದಿಂದ ಸರ್ವನಾಶ!\n\nಒಂದು ವಸ್ತುವಿನ ನಿರಂತರ ಸಂಪರ್ಕದಿಂದ ನಮಗೆ ಅದರ ಮೇಲೆ ಮೋಹ ಬೆಳೆಯುತ್ತದೆ. ಮೊದಲು ಪರಿಚಯ,\nಪರಿಚಯದಿಂದ ಸ್ನೇಹ, ನಂತರ ಆ ಸ್ನೇಹವನ್ನು ಹಚ್ಚಿಕೊಳ್ಳುವುದು(attachment). ನಂತರ ಅವರು\nನನ್ನ ವರಾಗಬೇಕು ಎನ್ನು ವ ಆಸೆ. ನಾವು ಆಸೆ ಪಟ್ಟ ತೆ ನೆರವೇರದಾಗ ಕ್ರೋಧ. ಈ ಕ್ರೋಧದ ಮೂಲ ಪ್ರೀತಿ!\nಕೋಪಕ್ಕೆ ಮೂಲ ಕಾರಣ ಕಾಮನೆ. ನಮಗೆ ಕೋಪ ಬಾರದಂತೆ ತಡೆಯಬೇಕಾದರೆ ಮೊದಲು ಕಾಮನೆಯನ್ನು\nತೊರೆಯಬೇಕು. ಆಸೆ. ಕಡಿಮೆಯಾದಂತೆ ಸಿಟ್ಟು ಕಡಿಮೆಯಾಗುತ್ತದೆ. ಅಂಟಿಸಿಕೊಳ್ಳುವುದು ಅಥವಾ\nಹಚ್ಚಿಕೊಳ್ಳುವುದರಿಂದ ಆಸೆ ಆಕಾಂಕ್ಷೆಗಳು ಬೆಳೆಯುತ್ತವೆ. ಅದು ಈಡೇರದಿದ್ದಾಗ ಕೋಪ. ಕೋಪದಿಂದ\nಸಮ್ಮೋಹ. ಅಂದರೆ ಅಸಂಗತವಾದ ವಿಚಾರಗಳು ತಲೆಯಲ್ಲಿ ಬಂದು ಮಾಡಬಾರದ್ದನ್ನು ಮಾಡುವ ಬಯಕೆ.\nಇದರಿಂದ ಯುಕ್ತಾಯುಕ್ತಗಳನ್ನು ವಿಶ್ಲೇಷಣೆ ಮಾಡುವ ಶಕ್ತಿ ಹೊರಟು ಹೋಗಿ, ತಪ್ಪನ್ನೇ ಸರಿ ಎಂದು ಸಮರ್ಥನೆ\nಮಾಡುವ ಮಟ್ಟಕ್ಕೆ ನಾವು ಇಳಿಯುತ್ತೇವೆ. ಪಲಿತಾಂಶ: ಪ್ರತೀಕಾರ ಮಾಡಬೇಕು ಎನ್ನುವ ಹಠ. ಅದರಿಂದ\nಪೂರ್ತಿ ತಿಳಿಗೇಡಿತನ ಮತ್ತು ಕೊನೆಗೆ ಆತ್ಮದ ಅಧಃಪತನ- ವಿನಾಶ-ಸರ್ವನಾಶ!\n\nಬುದ್ಧಿ ನಾಶವಾದಾಗ ಮನಸ್ಸು ಸತ್ತಂತೆ. ಅದರಿಂದ ಜೀವ ನರಕದ ದಾರಿಯಲ್ಲಿ ಹೋಗುವಂತಾಗುತ್ತದೆ. ಇದು\nಅಧಃಪಾತದ ದಾರಿ. ನಾವು ಎತ್ತರಕ್ಕೇರಬೇಕೆಂದರೆ ಪರಮಾತ್ಮನ ಮಹತ್ವವನ್ನು ಅರಿತು ಅವನಿಗೆ\nಶರಣಾಗಬೇಕು. ಒಳ್ಳೆಯ ದಾರಿಯಲ್ಲಿ ಮನಸ್ಸು ಚಿಂತನೆ ಮಾಡಿದಾಗ ಆತ್ಮ ಎತ್ತರಕ್ಕೇರಲು ಸಾಧ್ಯ. ಇದಕ್ಕೆ\nಮೊದಲು ನಾವು ಹಚ್ಚಿಕೊಳ್ಳುವುದನ್ನು(attachment) ಕಡಿಮೆ ಮಾಡಬೇಕು. ಇದರರ್ಥ ಯಾರನ್ನೂ\nಪ್ರೀತಿಸಬಾರದು, ಸ್ನೇಹ ಬೆಳೆಸಬಾರದು ಎಂದರ್ಥವಲ್ಲ. ಪ್ರೀತಿ ಇರಲಿ, ಸ್ನೇಹವಿರಲಿ, ಆದರೆ ಮೋಹ ಬೇಡ.\nಬಂದಿದ್ದು ಬರಲಿ ಎನ್ನು ವ ದೃಢ ನಿರ್ಧಾರವಿರಲಿ. ಹೀಗೇ ಆಗಬೇಕು-ಹಾಗೇ ಆಗಬೇಕು ಎನ್ನು ವ ಅತಿಮೋಹ\nದುಃಖಕ್ಕೆ _ ಕಾರಣ. ಎಲ್ಲವುದರ ಜೊತೆಗಿದ್ದು, ಎಲ್ಲರನ್ನೂ ಪ್ರೀತಿಸುವುದು-ಆದರೆ. ಹಚ್ಚಿಕೊಳ್ಳದೇ\nಇರುವುದು(attachment). ಇದೇ ಸಾಧನೆಯ, ಸಂತೋಷದ ಮೂಲ ಮಂತ್ರ.\n\nಮನಸ್ಸು ಯಾವಾಗಲೂ ಪ್ರಸನ್ನವಾಗಿರಬೇಕು. ಪ್ರಸನ್ನತೆ ಇಲ್ಲದಿದ್ದಾಗ ಮಾನಸಿಕವಾಗಿ, ದೈಹಿಕವಾಗಿ ನಾವು\nಆರೋಗ್ಯವನ್ನು ಕಳೆದುಕೊಳ್ಳುತ್ತೇವೆ. ಎಂತಹ ಪ್ರಸಂಗದಲ್ಲೂ ತಲೆ ಕೆಡಿಸಿಕೊಳ್ಳದೇ ಹಾಯಾಗಿರುವುದು\nಪ್ರಸನ್ನತೆ. ಇದನ್ನು ಗಳಿಸುವುದು ಹೇಗೆ ಎನ್ನುವ ಚಿತ್ರಣ ಮುಂದಿನ ಶ್ಲೋಕ.\n",
  "2.64": "ರಾಗ ದ್ವೇಷ ವಿಮುಕ್ತೆಃ ತು ವಿಷಯಾನ್‌ ಇಂದ್ರಿಯ್ಯಃ ಚರನ್‌ |\nಆತ್ಮವಶ್ಯೈಃ ವಿಧೇಯ ಆತ್ಮಾ ಪ್ರಸಾದಮ್‌ ಅಧಿಗಚ್ಛತಿ -. ಒಲವು ಹಗೆತನಗಳಿಂದ ಪಾರಾಗಿ ತನ್ನ\nಹಿಡಿತದಲ್ಲಿರುವ ಇಂದ್ರಿಯಗಳಿಂದ ವಿಷಯಗಳನ್ನು ಅನುಭವಿಸುವಾಗಲೂ, ಅಂಕೆ ತಪ್ಪದವನ ಮನಸ್ಸು\nತಿಳಿಗೊಳ್ಳುತ್ತದೆ.\nಇಂದ್ರಿಯ ನಿಗ್ರಹ ಅಥವಾ ಹಚ್ಚಿಕೊಳ್ಳದೇ ಇರುವುದು ಅಂದರೆ ಎಲ್ಲಾ ವಿಷಯ ಭೋಗಗಳನ್ನು ತೊರೆದು\nಪ್ರಾಪಂಚಿಕ ವ್ಯವಹಾರದಿಂದ ದೂರಸರಿದು ಕಣ್ಮುಚ್ಚಿ ಕುಳಿತುಕೊಳ್ಳುವುದಲ್ಲ. ಇಂದ್ರಿಯದಿಂದ ವಿಷಯ ಗ್ರಹಿಸು,\nಅದು ನಿರಂತರ. ಆದರೆ ಅದರಿಂದ ಪ್ರಭಾವಿತನಾಗಿ ಅದರ ದಾಸನಾಗಬೇಡ ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ವಿಷಯಗಳನ್ನು\nಇಂದ್ರಿಯಗಳಿಂದ ಅನುಭವಿಸು, ಆದರೆ ವಿಷಯಗಳಿಗೆ ರಾಗ-ದ್ವೇಷಗಳ ಹವ್ಯಾಸವನ್ನು ಅಂಟಿಸಬೇಡ. ಏನು\nಬಂತೋ ಹಾಗೇ ಅನುಭವಿಸು. ಇಂತಹ ಮನೋವೃತ್ತಿಯನ್ನು ಬೆಳೆಸಿಕೊಂಡಾಗ ಇಂದ್ರಿಯ ಯಾವ\nವಿಷಯವನ್ನು ಗ್ರಹಿಸಿದರೂ ಅಪಾಯವಿಲ್ಲ. ತಟಸ್ಥ ಮನಸ್ಸಿನಿಂದ ಯಾವುದೇ ವಿಷಯ ಕೇಳುವುದರಿಂದ,\nನೋಡುವುದರಿಂದ ಯಾವ ಅಪಾಯವೂ ಇಲ್ಲ. ಇಲ್ಲಿ ತಟಸ್ಥ ಮನಸ್ಸು ಅನ್ನುವುದಕ್ಕೆ ಉದಾಹರಣೆ ಎಂದರೆ,\nಕೆಲವೊಮ್ಮೆ, ನಾವು ನಮ್ಮ ಸ್ನೇಹಿತರನ್ನು ದಾರಿ ಮಧ್ಯದಲ್ಲಿ ಭೇಟಿಯಾಗುತ್ತೇವೆ. ನಾವು ಅಲ್ಲಿ ಕುಳಿತು\nಸಂಭಾಷಣೆ ಮಾಡುತ್ತೇವೆ. ಆದರೆ ನಂತರ ಯಾರಾದರೂ ಬಂದು ನಿನ್ನ ಸ್ನೇಹಿತ ಯಾವ ಬಣ್ಣದ ಬಟ್ಟೆ ಧರಿಸಿದ್ದ\nಎಂದು ಕೇಳಿದರೆ ನಮಗೆ ಗೊತ್ತಿರುವುದಿಲ್ಲ. ನಾವು ನೋಡಿರುತ್ತೇವೆ, ಆದರೆ ಗಮನಿಸಿರುವುದಿಲ್ಲ. ಏಕೆಂದರೆ\nಅದರ ಅಗತ್ಯವಿರುವುದಿಲ್ಲ. ಇದೇ ರೀತಿ ಮನಸ್ಸನ್ನು ತಟಸ್ಥವಾಗಿಟ್ಟು ಯಾವ ವಿಷಯ ಗ್ರಹಿಸಿದರೂ\nಅಪಾಯವಿಲ್ಲ. ಇದರಿಂದ ಇಂದ್ರಿಯಗಳು ಅಧೀನವಾಗಿರುತ್ತವೆ. ಮನಸ್ಸು ವಿಧೇಯವಾಗಿರುತ್ತದೆ. ಒಳಗಿನಿಂದ\nನಿರ್ಲಿಪ್ರತೆಯನ್ನು ಬೆಳೆಸಿಕೊಂಡಾಗ ಎಲ್ಲರ ಜೊತೆಗಿದ್ದು ಏಕಾಂತತೆಯನ್ನು ಗಳಿಸಬಹುದು. ಎಲ್ಲರ ಜೊತೆ\n\nಬೆರೆತು ಬೇರೆಯಾಗಿರಬಹುದು. ಅಂತರಂಗದ ಪ್ರಪಂಚದಲ್ಲಿ ಬೇರೆಯಾಗಿರುವ ಸ್ಥಿತಿ ಇದು. ಈ ರೀತಿ ಬದುಕಲು\nಕಲಿತಾಗ ಮನಸ್ಸು ತಿಳಿಗೊಳ್ಳುತ್ತದೆ. ಯಾವಾಗಲೂ ಸಂತೋಷ ಉಕ್ಕಿ ಹೊರಬರುತ್ತಿರುತ್ತದೆ. ಸಾಧನೆ\nಸುಗಮವಾಗುತ್ತದೆ.",
  "2.65": "ಪ್ರಸಾದೇ ಸರ್ವ ದುಃಖಾನಾಮ್‌ ಹಾನಿಃ ಅಸ್ಯ ಉಪಜಾಯತೇ |\nಪ್ರಸನ್ನಚೇತಸಃ ಹಿ ಆಶು ಬುದ್ಧಿಃ ಪರಿ ಅವತಿಷ್ಠತಿ--ಮನಸ್ಸು ತಿಳಿಗೊಂಡಾಗ ಸಾಧಕನ ಎಲ್ಲಾ ದುಗುಡಗಳು\nಇಲ್ಲವಾಗುತ್ತವೆ. ಏಕೆಂದರೆ ಬಗೆ ತಿಳಿಗೊಂಡವನ ಬುದ್ಧಿ ಬೇಗನೆ ಭಗವಂತನಲ್ಲಿ ನೆಲೆಗೊಳ್ಳುತ್ತದೆ.\n\nಮನಸ್ಸು ಕೊಳೆಯಾದರೆ ಎಲ್ಲವೂ ಕೊಳೆ. ಮನಸ್ಸು ತಿಳಿಯಾದರೆ ಎಲ್ಲವೂ ತಿಳಿ. ಎಲ್ಲಾ ಸಮಸ್ಯೆ ಇರುವುದು\nಮನಸ್ಸು ಕೊಳೆಯಾಗುವುದರಿಂದ. ನಮಗೆ ನಮ್ಮ ಮನಸ್ಸಿನ ಸ್ವಚ್ಛತೆ ಬಗ್ಗೆ ಗಮನ ಇಲ್ಲದಿದ್ದರೆ ಇತರ ಎಲ್ಲಾ\nಕಾರ್ಯವೂ ವ್ಯರ್ಥ. ಮನಸ್ಸು ಸ್ವಚ್ಛವಾದರೆ ಮಡಿ. ಅದೇ ಪ್ರಸನ್ನವಾದ ಸ್ಥಿತಿ. ಮನಸ್ಸು ತಿಳಿಯಾದಾಗ ಸರ್ವ\nದುಃಖವೂ ತನ್ನಷ್ಟಕ್ಕೆ ತಾನೇ ಕಣ್ಮರೆಯಾಗುತ್ತದೆ. ಇದು ದುಃಖಾತೀತ ಆನಂದ ಸ್ಥಿತಿ.\n\nಮನಸ್ಸು ತಿಳಿಯಾಯಿತು ಎಂದರೆ ಅದು ಭಗವಂತನನ್ನು ತಿಳಿಯಲು ಸಹಾಯ ಮಾಡುತ್ತದೆ. ಕೊಳೆಯಾದ\nಮನಸ್ಸಿನಿಂದ ಭಗವಂತನ ಚಿಂತನೆ ಸಾಧ್ಯವಿಲ್ಲ. ಭಗವಂತನನ್ನು ತಿಳಿದ ಮೇಲೆ ದುಃಖವಿಲ್ಲ. ಬುದ್ಧಿ-ಗಟ್ಟಿಗೊಂಡು\nಭಗವಂತನ ಅಪರೋಕ್ಷ ಜ್ಞಾನದಲ್ಲಿ ನಿಂತುಬಿಡುತ್ತದೆ. ಈ ಸ್ಥಿತಿಯಲ್ಲಿ, ಯಾವ ದೆಸೆಯಲ್ಲಿ ಯೋಚನೆ ಹೋದರೂ\nಕೂಡಾ ಅದು ಭಗವಂತನಲ್ಲಿ ಹೋಗಿ ನಿಲ್ಲುತ್ತದೆ. ಯಾವುದನ್ನು ಕೇಳಿದರೂ, ಯಾವುದನ್ನು ನೋಡಿದರೂ, ಅದರ\nಹಿಂದೆ ಇರುವ ಜಗತ್ತಿನ ಮೂಲ ಶಕ್ತಿಯ ಚಿಂತನೆ ಮನಸ್ಸಿಗೆ ಬಂದುಬಿಡುತ್ತದೆ. ಆಗ ಯಾವುದೋ ಸಣ್ಣ\nಸಂಗತಿಗಾಗಿ ಕೊರಗುವ ಪ್ರಶ್ನೆಯೇ ಉಳಿಯುವುದಿಲ್ಲ. ತಿಳಿಯಾದ ಮನಸ್ಸು ಭಗವನ್ಮಯವಾಗುತ್ತದೆ. ಒಮ್ಮೆ\nಭಗವಂತ ಮನಸ್ಸಿನಲ್ಲಿ ತುಂಬಿದ ಎಂದರೆ ಸರ್ವವೂ ಆನಂದಮಯ. ಆನಂತರ ದುಃಖವೆಂಬುವುದಿಲ್ಲ. ಈ\nಆನಂದ ಅಪರಿಮಿತ.\n",
  "2.66": "ನ ಅಸ್ತಿ ಬುದ್ಧಿಃ ಅಯುಕ್ತಸ್ಯ ನ ಚ ಅಯುಕ್ತಸ್ಯ ಭಾವನಾ |\n\nನ ಚ ಅಭಾವಯತಃ ಶಾಂತಿಃ ಅಶಾಂತಸ್ಯ ಕುತಃ ಸುಖಮ್‌--ಮನಸ್ಸು ಮಣಿಸದವನಿಗೆ ತಿಳಿಯಾದ ತಿಳಿವಿಲ್ಲ.\nಮನಸ್ಸು ಮಣಿಸದವನಿಗೆ ಧ್ಯಾನವೂ ಇಲ್ಲ. ಧ್ಯಾನ ಇರದವನಿಗೆ ಮುಕ್ತಿಯಿಲ್ಲ[ಭಗವಂತನಲ್ಲಿ ಬಗೆ ನೆಲೆಸದು].\nಮುಕ್ತನಾಗದವನಿಗೆ[ಭಗವಂತನಲ್ಲಿ ಬಗೆ ನೆಡದವನಿಗೆ] ಎಲ್ಲಿಯ ಸುಖ?\n\nಸುಖ ಬೇಕಿದ್ದರೆ ಶಾಂತಿ ಬೇಕು. ಮನಸ್ಸು ಪ್ರಸನ್ನವಾಗದೆ ವಿಕ್ಷಿಪ್ತವಾಗಿದ್ದರೆ ಅದು ಭಗವಂತನನ್ನು ಹೋಗಿ\nಸೇರುವುದಿಲ್ಲ. ಯಾರ ಮನಸ್ಸು ಭಗವಂತನಲ್ಲಿ ಸಂಯೋಗ ಹೊಂದುವುದಿಲ್ಲವೋ ಅವನಿಗೆ ಅಪರೋಕ್ಷವಿಲ್ಲ.\nಅಂತವನ ಮನಸ್ಸು ತಿಳಿಯಾಗದು. ಇಂತವರು ಏಕಾಗ್ರವಾಗಿ ಚಿಂತಿಸಲು ಸಾಧ್ಯವಿಲ್ಲ. ಏಕಾಗ್ರವಾಗಿ\nಚಿಂತಿಸದ ಹೊರತು ಯಥಾರ್ಥ ಜ್ಞಾನವಿಲ್ಲ. ಇಂಥವರಿಗೆ ಧ್ಯಾನ ಅಸಾಧ್ಯ. ಇಲ್ಲಿ ಧ್ಯಾನ ಅಂದರೆ\nಏಕಾಗ್ರವಾಗಿ ಒಂದು ವಸ್ತುವಿನ ಬಗ್ಗೆ ಚಿಂತಿಸುವುದು. ಯಾವುದೇ ಒಂದು ವಸ್ತುವಿನ ಬಗ್ಗೆ ನಮಗೆ ಖಚಿತವಾದ\nಅರಿವು ಬರಬೇಕಾದರೆ ನಮಗೆ ಏಕಾಗ್ರತೆ ಬೇಕು. ಅದನ್ನೇ ಇಲ್ಲಿ 'ಭಾವನಾ' ಎಂದಿದ್ದಾರೆ. ಮನಸ್ಸು\nಏಕಾಗ್ರವಾದರೆ ಮಾತ್ರ ಆಳವಾದ ಚಿಂತನೆ ಸಾಧ್ಯ. ಯಾವುದನ್ನೂ ಆಳವಾಗಿ ಚಿಂತಿಸದ ಹೊರತು ಅದರ ಬಗ್ಗೆ,\nಅದರ ವೈಶಾಲ್ಯತೆ ಬಗ್ಗೆ ಅರಿವು ಮೂಡದು. ಹೀಗೆ ಆಳಕ್ಕಿಳಿದು ಚಿಂತನೆ ಮಾಡದವನಿಗೆ ಶಾಂತಿ ಇಲ್ಲ. ಇಲ್ಲಿ\nಶಾಂತಿ ಎನ್ನುವುದಕ್ಕೆ ಎರಡು ಅರ್ಥವಿದೆ. ಮೇಲ್ನೋಟಕ್ಕೆ ಶಾಂತಿ ಅಂದರೆ ಆನಂದಮಯವಾದ ಸ್ಥಿತಿ.\nಶಾಸ್ತ್ರಕಾರರ ಪ್ರಕಾರ ಜೀವನಿಗೆ ಪೂರ್ಣ ಆನಂದದ ಸ್ಥಿತಿ ಅಂದರೆ ಮೋಕ್ಷ. ಆದ್ದರಿಂದ ಯಾರು ಧ್ಯಾನದಿಂದ\nಭಗವಂತನನ್ನು ಕಂಡುಕೊಳ್ಳುವುದಿಲ್ಲವೋ ಅವನಿಗೆ ಮೋಕ್ಷವಿಲ್ಲ. ಮೋಕ್ಷದ ದಾರಿಯಲ್ಲಿ ಸಾಗದವನಿಗೆ\nಸುಖವಿಲ್ಲ. ಇನ್ನು ಶಾಂತಿ ಎಂದರೆ ಆನಂದದ ತುತ್ತತುದಿ ಅಥವಾ ಪರಾಕಾಷ್ಠೆ. ಮನಸ್ಸು ಭಗವಂತನಲ್ಲಿ\nನೆಲೆಗೊಂಡಾಗ ನಮಗೆ ಶಾಂತಿ.\n\nಹೀಗೆ ಇಂದ್ರಿಯಗಳನ್ನು ಸಂಯಮ ಮಾಡಿಕೊಂಡು, ಮನಸ್ಸನ್ನು ಏಕಾಗ್ರಗೊಳಿಸಿ, ಅದರಲ್ಲಿ ಆಳವಾಗಿ ಚಿಂತನೆ\nಮಾಡಿ, ಸತ್ಯವನ್ನು ಕಂಡುಕೊಳ್ಳಬೇಕು. ನಾವು ಹೊರ ಪ್ರಪಂಚವನ್ನು ಬಿಟ್ಟು ಒಳ ಪ್ರಪಂಚದಲ್ಲಿ ಆಳವಾಗಿ\nಮುಳುಗದ ಹೊರತು, ಸತ್ಯದ ಸಾಕ್ಷಾತ್ಕಾರವಾಗದು. ಸತ್ಯದ ಸಾಕ್ಷಾತ್ಕಾರವಾಗದ ಹೊರತು ಸುಖವಿಲ್ಲ.\n",
  "2.67": "ಇಂದ್ರಿಯಾಹಾಂ ಹಿ ಚರತಾಮ್‌ ಯತ್‌ ಮನಃ ಅನುವಿಧೀಯತೇ |\nತತ್‌ ಅಸ್ಯ ಹರತಿ ಪ್ರಜ್ಞಾಮ್‌ ವಾಯುಃ ನಾವಮ್‌ ಇವ ಅಂಭಸಿ--ವಿಷಯಗಳತ್ತ ಹರಿಯುವ ಇಂದ್ರಿಯಗಳ ಬೆನ್ನು\nಹತ್ತುವಂತೆ ಮನಸ್ಸು ರೂಪುಗೊಂಡಿದೆಯಲ್ಲವೇ? ಆದ್ದರಿಂದ, ಅದು ಸಾಧಕನ ಅರಿವನ್ನು ದಾರಿಗೆಡಿಸಿಬಿಡುತ್ತದೆ-\nಕಡಲಲ್ಲಿ ಬಿರುಗಾಳಿ ಹಡಗನ್ನು ಹೇಗೆ ದಾರಿ ತಪ್ಪಿಸುತ್ತದೋ ಹಾಗೆ.\n\nಇಷ್ಟೆಲ್ಲಾ ಗಹನವಾದ ವಿಚಾರ ಇದ್ದರೂ ಕೂಡಾ, ಮನಸ್ಸು ಏಕೆ ಅಂತರಂಗದ ಆಳಕ್ಕಿಳಿಯುವುದಿಲ್ಲ? ಅದು\nಸಹಜ ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಏಕೆಂದರೆ ಮನಸ್ಸಿಗೆ ಒಂದು ಸ್ವಭಾವವಿದೆ. ಯಾವುದನ್ನು ನಾವು ಅದಕ್ಕೆ ಅಭ್ಯಾಸ\n\nಮಾಡಿದೆವೋ ಅದನ್ನೇ ಆದು ಮೆಚ್ಚಿಕೊಳ್ಳುವುದು. ಹೊಸದನ್ನು ಅದು ನಿರಾಕರಿಸುತ್ತದೆ. ಹಾಗೂ\nಪರಿಚಿತವಾದುದನ್ನು ಮಾತ್ರ ಅದು ಇಷ್ಟಪಡುತ್ತದೆ. ಮನಸ್ಸಿಗೆ ಒಳಪ್ರಪಂಚ ಅಪರಿಚಿತ. ಆದ್ದರಿಂದ ಅದು\nಒಳಪ್ರಪಂಚದತ್ತ ಹರಿಯುವುದಿಲ್ಲ. ಮನಸ್ಸಿಗೆ ಗಟ್ಟಿಯಾಗಿ ಹೇಳಿದರೆ ಅದು ಅಂತರ್ಮುಖವಾಗುತ್ತದೆ; ಆದರೆ ಆ\nಪ್ರಯತ್ನ ನಾವು ಮಾಡುವುದಿಲ್ಲ! ಈ ಅಪಾಯವನ್ನು ಈ ಶ್ಲೋಕದಲ್ಲಿ ಕೃಷ್ಣ ವಿವರಿಸಿದ್ದಾನೆ.\n\nಮನಸ್ಸಿಗೆ ನಾವು ಬಾಲ್ಯದಿಂದ ಎನನ್ನು ಅಭ್ಯಾಸ ಮಾಡಿಸಿದ್ದೆವೋ ಅದರ ಹಿಂದೆ ಅದು ಹೋಗುತ್ತದೆ.\nಉದಾಹರಣೆಗೆ ಬಾಲ್ಯದಿಂದಲೂ ಶಾಖಾಹಾರಿಯಾಗಿದ್ದವನಿಗೆ ಮಾಂಸವನ್ನು ಕಂಡಾಗ ಅಸಹ್ಯ ಎನಿಸುತ್ತದೆ.\nಆದರೆ ಅದೇ ಮಾಂಸ ಮಾರುವವ ಮಾಂಸದ ಮಧ್ಯದಲ್ಲೇ ಇದ್ದು ಅದನ್ನೇ ಬೇಯಿಸಿ ತಿಂದರೂ ಅವನಿಗೆ ಹೇಸಿಕೆ\nಅನಿಸುವುದಿಲ್ಲ. ಇದೆಲ್ಲವೂ ಮನಸ್ಸಿಗೆ ನಾವು ಕೊಡುವ ತರಬೇತಿ. ಮನಸ್ಸು ನಿರಂತರ ಯಾವುದನ್ನು\nನೋಡುತ್ತದೋ ಅದನ್ನೇ ರೂಢಿ ಮಾಡಿಕೊಳ್ಳುತ್ತದೆ. ಆ ರೀತಿ ಮನಸ್ಸು ಭಗವಂತನಿಂದ ನಿರ್ಮಿಸಲ್ಪಟ್ಟಿದೆ.\nಇಂದ್ರಿಯಗಳು ನಿತ್ಯ ಯಾವುದನ್ನು ನೋಡುತ್ತವೋ ಅದನ್ನು ಮೆಚ್ಚುವಂತಹ ಸ್ವಭಾವವನ್ನು ಭಗವಂತ ಮನಸ್ಸಿಗೆ\nಕೊಟ್ಟಿದ್ದಾನೆ. ಇಂತಹ ಮನಸ್ಸಿನ ಸ್ವಭಾವವನ್ನು ಅರಿಯದಿದ್ದರೆ ಅಪಾಯಕಾರಿ. ಅದು ನಮ್ಮ ಪ್ರಜ್ಞೆಯನ್ನು\nಅಪಹಾರ ಮಾಡಿಬಿಡುತ್ತದೆ. ಇದನ್ನು ಒಂದು ಒಳ್ಳೆಯ ದೃಷ್ಟಾಂತದ ಮುಖೇನ ಕೃಷ್ಣ ವಿವರಿಸಿದ್ದಾನೆ:\n\nನಾವು ಹಾಯಿ ದೋಣಿಯಲ್ಲಿ ಪ್ರಯಾಣಿಸುವ ನಾವಿಕನಂತೆ. ನಮ್ಮ ಮನಸ್ಸು ಆ ದೋಣಿಗೆ ಕಟ್ಟಿದ ಬಟ್ಟೆ. ಒಂದು\nವೇಳೆ ನಮಗೆ ಈ ಬಟ್ಟೆಯನ್ನು ತಿರುಗಿಸಿ ನಮಗೆ ಬೇಕಾದಂತೆ ದೋಣಿಯನ್ನು ನಿಯಂತ್ರಿಸುವ ಕಲೆ\nಗೊತ್ತಿಲ್ಲದಿದ್ದರೆ, ಗಾಳಿ ಬೀಸಿದತ್ತ ನಾವು ಹೋಗುತ್ತೇವೆಯೇ ಹೊರತು ನಮಗೆ ತಲುಪಬೇಕಾದಲ್ಲಿಗಲ್ಲ. ಈ\nದೃಷ್ಟಾಂತ ತುಂಬಾ ಔಚಿತ್ಯಪೂರ್ಣವಾಗಿದೆ. ಒಂದು ವೇಳೆ ನಾವು ನಮ್ಮ ಮನಸ್ಸನ್ನು ನಿಯಂತ್ರಿಸುವ\nಕಲೆಯನ್ನು ಕಲಿಯದಿದ್ದರೆ ಬದುಕು ಛಿದ್ರ-ವಿಛಿದ್ರವಾಗುತ್ತದೆ. ಬಿರುಗಾಳಿಗೆ ಸಿಕ್ಕ ತರಗೆಲೆಯಂತಾಗುತ್ತದೆ ಎನ್ನುವ\nಎಚ್ಚರವನ್ನು ಕೃಷ್ಣ ಇಲ್ಲಿ ಕೊಟ್ಟಿದ್ದಾನೆ.",
  "2.68": "ತಸ್ಮಾತ್ ಯಸ್ಯ ಮಹಾಬಾಹೋ ನಿಗೃಹೀತಾನಿ ಸರ್ವಶಃ |\nಇಂದ್ರಿಯಾಣಿ ಇಂದ್ರಿಯಾರ್ಥೇಭ್ಯಃ ತಸ್ಯ ಪ್ರಜ್ಞಾ ಪ್ರತಿಷ್ಠಿತಾ -- ಆದ್ದರಿಂದ ಓ ಮಹಾವೀರಾ, ಯಾರ ಇಂದ್ರಿಯಗಳು ಎಲ್ಲಾ ಬಗೆಯಿಂದಲೂ ಇಂದ್ರಿಯ ವಿಷಯಗಳಿಂದ ಪಾರಾಗಿ ಹಿಡಿತದಲ್ಲಿರುವವೋ ಅವನ ಅರಿವು ಗಟ್ಟಿಗೊಂಡಿರುತ್ತದೆ.",
  "2.69": "ಯಾ ನಿಶಾ ಸರ್ವಭೂತಾನಾಂ ತಸ್ಯಾಮ್‌ ಜಾಗರ್ತಿ ಸಂಯಮೀ।\n\nಯಸ್ಯಾಮ್‌ ಜಾಗ್ರತಿ ಭೂತಾನಿ ಸಾ ನಿಶಾ ಪಶ್ಯತಃ ಮುನೇಃ - ಯಾವುದು ಎಲ್ಲಾ ಜೀವಿಗಳಿಗೆ ಕತ್ತಲ\nಕಗ್ಗಂಟೋ ಅಂಥಲ್ಲಿ ಇಂದ್ರಿಯಗಳನ್ನು ಗೆದ್ದ. ಯೋಗಿ ಎಚ್ಚರವಿರುತ್ತಾನೆ. ಎಲ್ಲಾ ಜೀವಿಗಳು ಎಲ್ಲಿ\nಎಚ್ಚರವಿರುವರೋ-ಅದು ಬಲ್ಲ ಚಿಂತಕನಿಗೆ ನಟ್ಟಿರುಳು.\n\nಸಾಮಾನ್ಯ ಮನುಷ್ಯನಿಗೆ ಯಾವುದು ಹಗಲೋ ಅದು ಸತ್ಯದ ಸಾಕ್ಷಾತ್ಕಾರವಾದವನಿಗೆ ರಾತ್ರಿ. ಜಗತ್ತಿನ ಎಲ್ಲಾ\nಜೀವ ಜಾತಕ್ಕೆ ಯಾವುದು ರಾತ್ರಿಯೋ ಅದು ಸಾಧಕನಿಗೆ ಹಗಲು. ಅಂದರೆ ನಿಜವಾದ ಸಾಧಕ ನಮ್ಮ\nರಾತ್ರಿಯಲ್ಲಿ ಎಚ್ಚರವಿರುತ್ತಾನೆ, ಹಾಗೂ ಲೌಕಿಕ ವ್ಯವಹಾರವೆಂಬ ನಮ್ಮ ಹಗಲು ಅವನಿಗೆ ರಾತ್ರಿ. ಲೌಕಿಕ\nಪ್ರಪಂಚದಲ್ಲಿ ಅವನಿಗೆ ಪ್ರವೃತ್ತಿಯೇ ಇರುವುದಿಲ್ಲ. ಆತ ನಮಗೆ ಒಬ್ಬ ಮುಗ್ಧನಂತೆ, ಮಗುವಂತೆ ಕಾಣಬಹುದು.\nಆತನ ಜ್ಞಾನದ ಬಗ್ಗೆ ಅರಿವಿಲ್ಲದವನಿಗೆ ಆತನೊಬ್ಬ ಹುಚ್ಚನಂತೆ ಕಂಡರೆ ಆಶ್ಚರ್ಯವಿಲ್ಲ! ಏಕೆಂದರೆ ಆತ ಲೌಕಿಕ\nಪ್ರಪಂಚದೊಂದಿಗಿದ್ದು, ಅದರೊಂದಿಗೆ ಬೆರೆಯದೇ ತನ್ನ ಅಂತರಂಗದ ಆನಂದವನ್ನು ಸದಾ ಸವಿಯುತ್ತಿರುತ್ತಾನೆ.\nಒಬ್ಬ ಜ್ಞಾನಿ ಭಗವಂತನನ್ನು ಕಂಡಾಗ ಆತನಿಗೆ ಉಳಿದದ್ದೆಲ್ಲಾ ಕತ್ತಲು. ಅದ್ಭುತವಾದ ಸಂಗತಿಯನ್ನು ಕಂಡ\nವಿಸ್ಮಯದಲ್ಲಿ ತದೇಕಚಿತ್ತನಾಗಿ ಅದನ್ನೇ ನೋಡುತ್ತಿರುತ್ತಾನೆ. ಭಗವಂತನನ್ನು ಕಾಣಬೇಕಾದರೆ ನಾವು ಸದಾ\nಶಾಸ್ತ್ರದ ಶ್ರವಣ ಮಾಡಬೇಕು. ಕೇವಲ ಶ್ರವಣ ಮಾಡಿದರೆ ಸಾಲದು, ಶ್ರವಣದ ನಂತರ ಮನನ-ನಿಧಿಧ್ಯಾಸನ\nಅತಿ ಮುಖ್ಯ. ಇದನ್ನೇ \"ಆತ್ಮಾ ವಾ ಅರೇ ದ್ರಷ್ಟ ವ್ಯಃ ಶ್ರೋತವ್ಯಃ ಮಂತವ್ಯಃ ನಿಧಿಧ್ಯಾಸಿತವ್ಯಃ ಚ\" ಎಂದಿದ್ದಾರೆ.\nಮನನ ಶೀಲನಾದವ 'ಮುನಿ'; ಅವನೇ 'ಪಶ್ಯ' ಅಂದರೆ ಭಗವಂತನನ್ನು ಕಾಣಬಲ್ಲವ ಅಥವಾ ಕಂಡವ.\n\nಇಂದಿನ ಸಮಾಜದಲ್ಲಿ ಸತ್ಯದ ಸಾಕ್ಷಾತ್ಕಾರನಾದವನನ್ನು ಗುರುತಿಸುವುದು ಬಹಳ ಕಷ್ಟ. ಸಿದ್ಧ ಪುರುಷರೆಲ್ಲಾ\nಸತ್ಯವನ್ನು ಕಂಡವರಲ್ಲ! ಪವಾಡ ಮಾಡುವವರು ಭಗವಂತನನ್ನು ಕಂಡವರು ಎಂದು ಹೇಳಲಾಗುವುದಿಲ್ಲ.\nಏಕೆಂದರೆ ನಿಜವಾದ ಸಾಧಕ ಸಾಮಾನ್ಯವಾಗಿ ಪವಾಡ ಮಾಡುವುದಿಲ್ಲ. ತೀರಾ ಅನಿವಾರ್ಯವಾದಾಗ ಮಾತ್ರ\nಆತ ಪ್ರಪಂಚದ ಒಳಿತಿಗಾಗಿ ಪವಾಡ ಮಾಡಬಹುದು. ನಿರಂತರ ಸತ್ಯದ ಬಗ್ಗೆ ಅನ್ವೇಷಣೆ ಮಾಡಿ, ಸಿದ್ಧಿ\nಗಳಿಸಿದರೆ ಮಾತ್ರ ಸ್ಥಿತಪ್ರಜ್ಞರಾಗಲು ಸಾಧ್ಯ.\n",
  "2.70": "ಆಪೂರ್ಯಮಾಣಮ್‌ ಅಚಲಪ್ರತಿಷ್ಠಮ್‌ ಸಮುದ್ರಮ್‌ ಅಪಃ ಪ್ರವಿಶಂತಿ ಯಡದ್ವತ್‌ |\n\nತದ್ವತ್‌ ಕಾಮಾಃ ಯಮ್‌ ಪ್ರವಿಶಂತಿ ಸರ್ವೇ ಸಃ ಶಾಂತಿಮ್‌ ಅಪ್ನೋತಿ ನ ಕಾಮಕಾಮೀ--ತುಂಬಿದರೂ\nತುಳುಕದೇ ನಿಂತ ಕಡಲನ್ನು ಎಲ್ಲಾ ನೀರುಗಳು ಬಂದು ಸೇರುವಂತೆ, ಯಾರನ್ನು ಎಲ್ಲಾ ವಿಷಯಗಳು\nತುಂಬಿಯೂ ತುಳುಕದಂತೆ ಬಂದು ಸೇರುವವೋ ಅವನು ಮುಕ್ತಿ ಪಡೆಯುತ್ತಾನೆ. ಹೊರತು ಕೆಟ್ಟ ಬಯಕೆಗಳ\nಬೆನ್ನು ಹತ್ತಿದವನಲ್ಲ.\n\nಭಗವಂತನನ್ನು ಕಂಡವನು, ಸತ್ಯದ ಸಾಕ್ಷಾತ್ಕಾರವಾದವನು. ಭಗವಂತನನ್ನು ಕಾಣುವ ಸರಿ ದಾರಿಯಲ್ಲಿ\nನಡೆಯುವವನು ಹೇಗಿರುತ್ತಾನೆ ಎನ್ನುವ ವಿಷಯದ ಮೇಲೆ ಕೃಷ್ಣ ಇಲ್ಲಿ ಇನ್ನಷ್ಟು ವಿವರಣೆಯನ್ನು ಕೊಟ್ಟಿದ್ದಾನೆ:\nಆತನ ಮನಸ್ಸು ಸದಾ ಆನಂದವಾಗಿರುತ್ತದೆ. ಅದು ಭಗವಂತನಲ್ಲಿ ನೆಲೆಗೊಂಡಿರುತ್ತದೆ. ಆತ ಕಿರು\nತೊರೆಗಳಂತೆ. ಇರದೆ, ಕಡಲಿನಂತಿರುತ್ತಾನೆ. ಸಮುದ್ರಕ್ಕೆ ಎಲ್ಲಾ ನದಿಗಳು ಬಂದು ಸೇರಿದರೂ ಅದು\nಉಕ್ಕೇರುವುದಿಲ್ಲ. ಕಡಲು ಮಳೆ ಬಂದಾಗ ಉಕ್ಕಿ ಹರಿದು- ಬೇಸಿಗೆ ಬಂದಾಗ ಬತ್ತಿ ಹೋಗುವುದಿಲ್ಲ. ಅದೇ ರೀತಿ\nಸಾಧಕ. ಪ್ರಪಂಚದ ಎಲ್ಲಾ ಭೋಗಗಳು ಅವನನ್ನು ಪ್ರವೇಶಿಸಿದರೂ ಕೂಡಾ, ಆತ ವಿಚಲಿತನಾಗದೇ ಸುಖ-\nದುಃಖವನ್ನು ಮೀರಿ ನಿಲ್ಲುತ್ತಾನೆ. ಆತನ ಮನಸ್ಸು ಸದಾ ಪ್ರಸನ್ನವಾಗಿರುತ್ತದೆ. ಆತ ಭಗವಂತನಲ್ಲಿ ನಿಷ್ಠೆಯನ್ನಿಟ್ಟು\nಮೋಕ್ಷವನ್ನು ಪಡೆಯುತ್ತಾನೆ. ಆದರೆ ಬಯಕೆಗಳ ಬೆನ್ನು ಹತ್ತಿದವನು ಅದರಿಂದ ಈಚೆ ಬಾರದೆ ಎಂದೂ ನಿಜವಾದ\n\nಸುಖ ಕಾಣಲಾರ.\n",
  "2.71": "ವಿಹಾಯ ಕಾಮಾನ್‌ ಯಃ ಸರ್ವಾನ್‌ ಪುಮಾನ್‌ ಚರತಿ ನಿಸ್ಟೃಹಃ |\n\nನಿರ್ಮಮಃ ನಿರಹಂಕಾರಃ ಸಃ ಶಾಂತಿಮ್‌ ಅಧಿಗಚ್ಛತಿ--ಯಾರು ಎಲ್ಲಾ ವಿಷಯಗಳನ್ನು ಮನಸೋಲದೇ, ಕೆಟ್ಟ\nಆಸೆಗೆ ಬಲಿ ಬೀಳದೇ, ನಾನು ನನ್ನದು ಎಂಬ ಹಮ್ಮು ತೊರೆದು ಅನುಭವಿಸುತ್ತಾನೊ-ಅವನು ಮುಕ್ತಿ\nಪಡೆಯುತ್ತಾನೆ.\n\nಯಾರು ಭೋಗದ ಬಯಕೆಯನ್ನು ಬಿಟ್ಟು ಬಂದದ್ದನ್ನು ಸಂತೋಷವಾಗಿ ಅನುಭವಿಸುತ್ತಾನೋ, ಅವನು ನಿಜವಾದ\nಸಾಧಕನೆನಿಸುತ್ತಾನೆ. ಸೀಮಿತವಾದ ಆಹಾರ, ನಿದ್ದೆ ಮತ್ತು ಮೈಥುನವನ್ನು ಅಭ್ಯಾಸ ಮಾಡಿಕೊಂಡು,\nನಿರ್ಭಯವಾಗಿ ಸಂಪೂರ್ಣ ಭಗವಂತನ ರಕ್ಷಾ ಕವಚದ ಜ್ಞಾನದಲ್ಲಿದ್ದು, ಆಸೆ. ಆಕಾಂಕ್ಷೆಗಳಿಗೆ ಬಲಿ ಬೀಳದೆ,\nಯಾವುದೇ ಏರು-ಪೇರುಗಳಿಗೆ ವಿಚಲಿತನಾಗದೇ ಬದುಕುತ್ತಾನೆ. ಅವನು ನಿಜವಾದ 'ಮನುಷ್ಯ'ನೆನಿಸುತ್ತಾನೆ.\n\nಇಂತವನಿಗೆ ನಾನು-ನನ್ನದು ಎನ್ನುವ ಅಹಮ್‌ ಎಂದೂ ಇರುವುದಿಲ್ಲ ಹಾಗೂ ಆತ ಮುಕ್ತಿಯನ್ನು ಪಡೆಯುತ್ತಾನೆ.",
  "2.72": "ದ) ಗ ದ್‌ ೨%\n\nಏಷಾ ಬ್ರಾಹ್ಮೀ ಸ್ಥಿತಿಃ ಪಾರ್ಥ ನ ಏನಾಮ್‌ ಪ್ರಾಪ್ಯ ವಿಮುಹ್ಯತಿ |\n\nಸ್ಥಿತ್ವಾ ಅಸ್ಯಾಮ್‌ ಅಂತಕಾಲೇ ಅಪಿ ಬ್ರಹ್ಮನಿರ್ಬಾಣಮ್‌ ಖುಚ್ಛತಿ- - ಪಾರ್ಥಾ, ಇದು ಬ್ರಹ್ಮ ಜ್ಞಾನಿಯ ಗುರುತು.\nಇದನ್ನು ಪಡೆದು ಮತ್ತೆ ಮೈಮರೆಯುವುದಿಲ್ಲ. ಕೊನೆಯ ಕಾಲದಲ್ಲೂ ಈ ನೆಲೆಯಲ್ಲಿ ನಿಂತವನು ಕಾಯದಿಂದಲೂ\nಸಾಯದ ಪರತತ್ವವನ್ನು ಸೇರುತ್ತಾನೆ.\n\nಭಗವಂತನಲ್ಲಿ ನೆಲೆಗೊಳ್ಳತಕ್ಕಂತವನ ಲಕ್ಷಣ ಬ್ರಾಹ್ಮೀ ಸ್ಥಿತಿ. ಈವರೆಗೆ ಹೇಳಿರುವುದು ಒಬ್ಬ ಬ್ರಹ್ಮ ಜ್ಞಾನಿಯ\nಲಕ್ಷಣ. ಬ್ರಹ್ಮನಲ್ಲಿ ಸ್ಥಿತನಾದ ಬ್ರಹ್ಮ ಪ್ರಜ್ಞೆ ಜಾಗೃತನಾದವನ ಲಕ್ಷಣ. ಇಂತಹ ಬ್ರಹ್ಮಜ್ಞಾನಿಯನ್ನು ಆತನ ಬಾಹ್ಯ\nಕ್ರಿಯೆಯಿಂದಾಗಲೀ, ವೇಷ ಭೂಷಣದಿಂದಾಗಲೀ ಗುರುತಿಸಲಾಗದು. ಆತನ ಮಾನಸಿಕ ಸ್ಥಿತಿ ಆತನ ಸ್ಥಾನವನ್ನು\nತಿಳಿಸುತ್ತದೆ.\n\nತನ್ನ ಸಾವಿನ ಕೊನೇ ಕ್ಷಣದಲ್ಲೂ ಕೂಡಾ ಭಗವಂತನ ಪ್ರಜ್ಞೆ ಜಾಗೃತವಾಗಿದ್ದರೆ ಆತ ನೇರ ಮರು ಹುಟ್ಟಿಲ್ಲದ\nಮೋಕ್ಷವನ್ನು ಸೇರುತ್ತಾನೆ.\n\nಇತಿ ದ್ವಿತೀಯೋ$*ಧ್ಯಾಯಃ\nಎರಡನೇಯ ಅಧ್ಯಾಯ ಮುಗಿಯಿತು\n\nಅಧ್ಯಾಯ ಮೂರು\n\nಎರಡನೇ ಅಧ್ಯಾಯದಲ್ಲಿ ಭಗವಂತನ ಅರಿವು, ಆ ಅರಿವನ್ನು ಪಡೆಯುವ ಉಪಾಯವನ್ನು ಕೃಷ್ಣ ವಿವರಿಸಿದ. ಈ\nಉಪದೇಶದಲ್ಲಿ ಒಂದು ಕಡೆ ಜ್ಞಾನ ಎಲ್ಲವುದಕ್ಕಿಂತ ಶ್ರೇಷ್ಠ, ಜ್ಞಾನದ ಮುಂದೆ ಕರ್ಮ ಏನೂ ಅಲ್ಲ ಎನ್ನು ತ್ತಾನೆ\nಕೃಷ್ಣ. ಇನ್ನೊಂದು ಕಡೆ ಅರ್ಜುನನಲ್ಲಿ ತಾಮಸಿಕವಾದ ಯುದ್ಧವನ್ನು ಮಾಡು ಎನ್ನುತ್ತಾನೆ! ಜ್ಞಾನವೇ ಅತ್ಯಂತ\nಶ್ರೇಷ್ಟ ವಾದರೆ ಏಕೆ ಬೇಕು ಈ ತಾಮಸಿಕವಾದ ರಾಗ-ದ್ವೇಷವಿರುವ ಯುದ್ಧ? ಮೂರನೇ ಅಧ್ಯಾಯ ಅರ್ಜುನನ\nಈ ಪ್ರಶ್ನೆಯೊಂದಿಗೆ ಪ್ರಾರಂಭವಾಗುತ್ತದೆ.\n\nಅರ್ಜುನ ಉವಾಚ ।\nಜ್ಯಾಯಸೀ ಚೇತ್‌ ಕರ್ಮಣಸ್ತೇ ಮತಾ ಬುದ್ಧಿರ್ಜನಾರ್ದನ ।\nತತ್‌ ಕಿಂ ಕರ್ಮಣಿ ಘೋರೇ ಮಾಂ ನಿಯೋಜಯಸಿ ಕೇಶವ ॥೧॥\n\nಅರ್ಜುನಃ ಉವಾಚ- ಅರ್ಜುನ ಹೇಳಿದನು:\n\nಜ್ಯಾಯಸೀ ಚೇತ್‌ ಕರ್ಮಣಃ ತೇ ಮತಾ ಬುದ್ಧಿಃ ಜನಾರ್ದನ |\n\nತತ್‌ ಕಿಂ ಕರ್ಮಣಿ ಘೋರೇ ಮಾಮ್‌ ನಿಯೋಜಯಸಿ ಕೇಶವ - ಓ ಜನಾರ್ದನಾ, ಕಾಯಕಕ್ಕಿಂತ ಅರಿವೇ\nಹಿರಿದು ಎಂದು ನಿನ್ನ ಆಶಯವಾದರೆ, ಮತ್ತೇಕೆ ನನ್ನನ್ನು ಈ ಕೊಲ್ಲುವ ಕಾಯಕದಲ್ಲಿ ತೊಡಗಿಸುತ್ತಿರುವೆ\n\nಕೇಶವಾ?\n\nಕೃಷ್ಣ ಜ್ಞಾನ ಮತ್ತು ಕರ್ಮದ ಬಗ್ಗೆ ಕೊಟ್ಟ ವಿವರಣೆಯಿಂದ ಅರ್ಜುನನಿಗೆ ಗೊಂದಲವಾಗುತ್ತದೆ. ತನಗೆ ಯಾವ\nಮಾರ್ಗ ಉಚಿತ ಎನ್ನುವ ಪ್ರಶ್ನೆ ಆತನನ್ನು ಕಾಡುತ್ತದೆ. ಕೃಷ್ಣ ಒಮ್ಮೆ ಜ್ಞಾನ ಮಾರ್ಗದಲ್ಲಿ ಸಾಗು-ಅದು ಶ್ರೇಷ್ಠ\nಎನ್ನು ತ್ತಾನೆ; ಇನ್ನೊ ಮ್ಮೆ ಯುದ್ಧ ಮಾಡು ಅನ್ನು ತ್ತಾನೆ! ತಾನೇಕೆ ಶ್ರೇಷ್ಠವಾದ ಜ್ಞಾನ ಮಾರ್ಗದಲ್ಲಿ ಸಾಗಬಾರದು,\nಯುದ್ಧವನ್ನೇಕೆ ಮಾಡಬೇಕು ಎನ್ನುವ ಗೊಂದಲ ಅರ್ಜುನನದು. ಈ ಗೊಂದಲದಲ್ಲಿ ಅರ್ಜುನ ಕೃಷ್ಣನಲ್ಲಿ\nಕೇಳುತ್ತಾನೆ: “ಓ ಜನಾರ್ದನಾ, ಕರ್ಮಕ್ಕಿಂತ ಜ್ಞಾನ ಮಾರ್ಗ ಶ್ರೇಷ್ಠ ಎನ್ನುವುದು ನಿನ್ನ ಅಭಿಮತವಾದರೆ, ನನ್ನ\nಹತ್ತಿರ ಕರ್ಮ ಮಾಡು ಎಂದು ಏಕೆ ಹೇಳುತ್ತಿದ್ದೀಯ? ಯುದ್ಧ ಎನ್ನುವುದು ಘೋರ ರಾಗ-ದ್ವೇಷಗಳಿಂದ ತುಂಬಿದ\nತಾಮಸಕಾರ್ಯ. ಅದು ಅಧ್ಯಾತ್ಮ ಸಾಧನೆಗೆ ತೀರಾ ವಿರುದ್ಧವಾದ ಕರ್ಮ. ಹೀಗಿರುವಾಗ ನನ್ನನ್ನೇಕೆ ಈ\nಕಾರ್ಯದಲ್ಲಿ ತೊಡಗಿಸುತ್ತಿರುವೆ ಕೇಶವ?” ಎಂದು.\n\nಈ ಶ್ಲೋಕದಲ್ಲಿ ಅರ್ಜುನ ಶ್ರೀಕೃಷ್ಣನನ್ನು 'ಜನಾರ್ದನ' ಮತ್ತು “ಕೇಶವ' ಎನ್ನುವ ಎರಡು ವಿಶೇಷ ನಾಮದಿಂದ\nಸಂಬೋಧಿಸಿರುವುದನ್ನು ಕಾಣುತ್ತೇವೆ. ಇಲ್ಲಿ-ಪ್ರಶ್ನೆ ಮಾಡುತ್ತಿರುವ ಅರ್ಜುನನ ಭಾವ ಅಡಗಿದೆ. ಜನ-ಅರ್ದನ\nಅಂದರೆ ಜನರನ್ನು ನಾಶ ಮಾಡುವವ! ಇಲ್ಲಿ ಜನ ಅಂದರೆ ದುರ್ಜನ. ಜನಾರ್ದನ ಅಂದರೆ ದುರ್ಜನ ನಾಶಕ.\n“ದುಷ್ಟ ನಿಗ್ರಹಕ್ಕಾಗಿ ಅವತರಿಸಿದ ನೀನು, ನನ್ನಿಂದ ಈ ಕಾರ್ಯವನ್ನು ಮಾಡಿಸುತ್ತಿದ್ದೀಯ. ಆದರೆ ಇಲ್ಲಿ\nಸೇರಿರುವರೆಲ್ಲಾ ದುರ್ಜನರಲ್ಲ. ಹೀಗಿರುವಾಗ ಅವರನ್ನು ಕೊಲ್ಲುವ ಕರ್ಮ ಶ್ರೇಷ್ಠ ಹೇಗಾದೀತು? ಜನನ\n\nಮುಕ್ತಗೊಳಿಸಿ ಮೋಕ್ಷವನ್ನು ಕರುಣಿಸುವ ನೀನು, ನನ್ನಿಂದ ಗುರು ಹಿರಿಯರನ್ನು ಕೊಲ್ಲುವ ಈ ಘೋರ ಕರ್ಮವನ್ನು\nಏಕೆ ಮಾಡಿಸುತ್ತಿರುವೆ?”. ಎನ್ನುವುದು ಅರ್ಜುನನ ಪ್ರಶ್ನೆ. ಶ್ಲೋಕದ ಕೊನೆಯಲ್ಲಿ *ಕೇಶವ' ಎನ್ನುವ\nನಾಮವಿಶೇಷಣ ಅರ್ಜುನನ ಶರಣಾಗತಿಯನ್ನು ಸೂಚಿಸುತ್ತದೆ. ಕಾ*ಈಶ*ವ-ಕೇಶವ; ಇಲ್ಲಿ 'ಕಾ' ಎಂದರೆ\nಸೃಷ್ಟಿಗೆ ಕಾರಣವಾಗಿರುವ ಚತುರ್ಮುಖ ಬ್ರಹ್ಮ ; ಈಶ ಎಂದರೆ ಸಂಹಾರಕ್ಕೆ ಕಾರಣವಾಗಿರುವ ಶಂಕರ. ಕೇಶವ\nಅಂದರೆ ಸೃಷ್ಟಿ-ಸಂಹಾರಕ್ಕೆ ಕಾರಣವಾಗಿರುವ ಬ್ರಹ್ಮಶಕ್ತಿ ಮತ್ತು ಶಿವಶಕ್ತಿಯನ್ನೊಳಗೊಂಡ ಪರಶಕ್ತಿ. “ಸೃಷ್ಟಿ-ಸ್ಥಿತಿ-\nಸಂಹಾರ-ಮೋಕ್ಷಗಳಿಗೆ ಕಾರಣನಾದ ನೀನು ನನ್ನನ್ನು ಈ ಗೊಂದಲದಿಂದ ಪಾರು ಮಾಡು” ಎಂದು ಅರ್ಜುನ\nಶ್ರೀಕೃಷ್ಣನಲ್ಲಿ ಶರಣಾಗಿ ಬೇಡುತ್ತಾನೆ.\n\nವ್ಯಾಮಿಶ್ರೇಣ್ಯೇವ ವಾಕ್ಯೇನ ಬುದ್ಧಿಂ ಮೋಹಯಸೀವ ಮೇ |\nತದೇಕಂ ವದ ನಿಶ್ಚಿತ್ಯ ಯೇನ ಶ್ರೇಯೋಹಮಾಪ್ನಯಾಮ್‌ ॥೨॥\n\nವ್ಯಾಮಿಶ್ರೇಣ ಇವ ವಾಕ್ಯೇನ ಬುದ್ಧಿಮ್‌ ಮೋಹಯಸಿ ಇವ ಮೇ |\n\nತತ್‌... ಏಕಮ್‌ ವದ ನಿಶ್ಚಿತ್ಯ ಯೇನ ಶ್ರೇಯಃ ಅಹಮ್‌ ಅಪ್ಲುಯಾಮ್‌-ಇಬ್ಬಗೆಯ ಮಾತಿನಿಂದ ನನ್ನ\nನಿರ್ಧಾರಶಕ್ತಿಯನ್ನು ಗೊಂದಲಕ್ಕೀಡುಮಾಡುವಂತಿದೆ. ಆದ್ದರಿಂದ, ಒಂದನ್ನು ನಿರ್ಧರಿಸಿ ಹೇಳು: ಯಾವುದರಿಂದ\nನಾನು ಒಳಿತನ್ನು ಪಡೆದೇನು?\n\nಇಲ್ಲಿ 'ವ್ಯಾಮಿಶ್ರೇಣ' ಎಂದರೆ ವಿರೋಧಾಭಾಸ. “ಈ ರೀತಿ ಇಬ್ಬಗೆಯ\nಮಾತಿನಿಂದ ನನಗೆ ಯಾವುದು ಸರಿ-ಯಾವುದು ತಪ್ಪು ಎನ್ನುವ ತೀರ್ಮಾನ ಬರುತ್ತಿಲ್ಲ, ಹಾಗೂ ಅದನ್ನು\nತಿಳಿಯುವ ಶಕ್ತಿ ನನ್ನಲ್ಲಿಲ್ಲ. ನಿನ್ನ ಅಭಿಪ್ರಾಯವನ್ನು ನಾನು ಗ್ರಹಿಸಲಾರೆ. ಯಾವ ದಾರಿಯಲ್ಲಿ ನಡೆದರೆ ನಾನು\nಶ್ರೇಯಸ್ಸನ್ನು ಪಡೆದೇನು? ನನ್ನ ಬದುಕು ಸಾರ್ಥಕವಾಗುವ ನಿಶ್ಚಿತ ದಾರಿಯನ್ನು ಹೇಳು” ಎಂದು ಕೃಷ್ಣನಲ್ಲಿ\nಅರ್ಜುನ ಕೇಳಿಕೊಳ್ಳುತ್ತಾನೆ.\n\nಭಗವಾನುವಾಚ ।\nಲೋಕೇಸ್ಕ್ಮಿನ್‌ ದ್ವಿವಿದಾ",
  "3.1": "ಅಧ್ಯಾಯ ಮೂರು\n\nಎರಡನೇ ಅಧ್ಯಾಯದಲ್ಲಿ ಭಗವಂತನ ಅರಿವು, ಆ ಅರಿವನ್ನು ಪಡೆಯುವ ಉಪಾಯವನ್ನು ಕೃಷ್ಣ ವಿವರಿಸಿದ. ಈ\nಉಪದೇಶದಲ್ಲಿ ಒಂದು ಕಡೆ ಜ್ಞಾನ ಎಲ್ಲವುದಕ್ಕಿಂತ ಶ್ರೇಷ್ಠ, ಜ್ಞಾನದ ಮುಂದೆ ಕರ್ಮ ಏನೂ ಅಲ್ಲ ಎನ್ನು ತ್ತಾನೆ\nಕೃಷ್ಣ. ಇನ್ನೊಂದು ಕಡೆ ಅರ್ಜುನನಲ್ಲಿ ತಾಮಸಿಕವಾದ ಯುದ್ಧವನ್ನು ಮಾಡು ಎನ್ನುತ್ತಾನೆ! ಜ್ಞಾನವೇ ಅತ್ಯಂತ\nಶ್ರೇಷ್ಟ ವಾದರೆ ಏಕೆ ಬೇಕು ಈ ತಾಮಸಿಕವಾದ ರಾಗ-ದ್ವೇಷವಿರುವ ಯುದ್ಧ? ಮೂರನೇ ಅಧ್ಯಾಯ ಅರ್ಜುನನ\nಈ ಪ್ರಶ್ನೆಯೊಂದಿಗೆ ಪ್ರಾರಂಭವಾಗುತ್ತದೆ.\n\nಅರ್ಜುನ ಉವಾಚ ।\nಜ್ಯಾಯಸೀ ಚೇತ್‌ ಕರ್ಮಣಸ್ತೇ ಮತಾ ಬುದ್ಧಿರ್ಜನಾರ್ದನ ।\nತತ್‌ ಕಿಂ ಕರ್ಮಣಿ ಘೋರೇ ಮಾಂ ನಿಯೋಜಯಸಿ ಕೇಶವ ॥೧॥\n\nಅರ್ಜುನಃ ಉವಾಚ- ಅರ್ಜುನ ಹೇಳಿದನು:\n\nಜ್ಯಾಯಸೀ ಚೇತ್‌ ಕರ್ಮಣಃ ತೇ ಮತಾ ಬುದ್ಧಿಃ ಜನಾರ್ದನ |\n\nತತ್‌ ಕಿಂ ಕರ್ಮಣಿ ಘೋರೇ ಮಾಮ್‌ ನಿಯೋಜಯಸಿ ಕೇಶವ - ಓ ಜನಾರ್ದನಾ, ಕಾಯಕಕ್ಕಿಂತ ಅರಿವೇ\nಹಿರಿದು ಎಂದು ನಿನ್ನ ಆಶಯವಾದರೆ, ಮತ್ತೇಕೆ ನನ್ನನ್ನು ಈ ಕೊಲ್ಲುವ ಕಾಯಕದಲ್ಲಿ ತೊಡಗಿಸುತ್ತಿರುವೆ\n\nಕೇಶವಾ?\n\nಕೃಷ್ಣ ಜ್ಞಾನ ಮತ್ತು ಕರ್ಮದ ಬಗ್ಗೆ ಕೊಟ್ಟ ವಿವರಣೆಯಿಂದ ಅರ್ಜುನನಿಗೆ ಗೊಂದಲವಾಗುತ್ತದೆ. ತನಗೆ ಯಾವ\nಮಾರ್ಗ ಉಚಿತ ಎನ್ನುವ ಪ್ರಶ್ನೆ ಆತನನ್ನು ಕಾಡುತ್ತದೆ. ಕೃಷ್ಣ ಒಮ್ಮೆ ಜ್ಞಾನ ಮಾರ್ಗದಲ್ಲಿ ಸಾಗು-ಅದು ಶ್ರೇಷ್ಠ\nಎನ್ನು ತ್ತಾನೆ; ಇನ್ನೊ ಮ್ಮೆ ಯುದ್ಧ ಮಾಡು ಅನ್ನು ತ್ತಾನೆ! ತಾನೇಕೆ ಶ್ರೇಷ್ಠವಾದ ಜ್ಞಾನ ಮಾರ್ಗದಲ್ಲಿ ಸಾಗಬಾರದು,\nಯುದ್ಧವನ್ನೇಕೆ ಮಾಡಬೇಕು ಎನ್ನುವ ಗೊಂದಲ ಅರ್ಜುನನದು. ಈ ಗೊಂದಲದಲ್ಲಿ ಅರ್ಜುನ ಕೃಷ್ಣನಲ್ಲಿ\nಕೇಳುತ್ತಾನೆ: “ಓ ಜನಾರ್ದನಾ, ಕರ್ಮಕ್ಕಿಂತ ಜ್ಞಾನ ಮಾರ್ಗ ಶ್ರೇಷ್ಠ ಎನ್ನುವುದು ನಿನ್ನ ಅಭಿಮತವಾದರೆ, ನನ್ನ\nಹತ್ತಿರ ಕರ್ಮ ಮಾಡು ಎಂದು ಏಕೆ ಹೇಳುತ್ತಿದ್ದೀಯ? ಯುದ್ಧ ಎನ್ನುವುದು ಘೋರ ರಾಗ-ದ್ವೇಷಗಳಿಂದ ತುಂಬಿದ\nತಾಮಸಕಾರ್ಯ. ಅದು ಅಧ್ಯಾತ್ಮ ಸಾಧನೆಗೆ ತೀರಾ ವಿರುದ್ಧವಾದ ಕರ್ಮ. ಹೀಗಿರುವಾಗ ನನ್ನನ್ನೇಕೆ ಈ\nಕಾರ್ಯದಲ್ಲಿ ತೊಡಗಿಸುತ್ತಿರುವೆ ಕೇಶವ?” ಎಂದು.\n\nಈ ಶ್ಲೋಕದಲ್ಲಿ ಅರ್ಜುನ ಶ್ರೀಕೃಷ್ಣನನ್ನು 'ಜನಾರ್ದನ' ಮತ್ತು “ಕೇಶವ' ಎನ್ನುವ ಎರಡು ವಿಶೇಷ ನಾಮದಿಂದ\nಸಂಬೋಧಿಸಿರುವುದನ್ನು ಕಾಣುತ್ತೇವೆ. ಇಲ್ಲಿ-ಪ್ರಶ್ನೆ ಮಾಡುತ್ತಿರುವ ಅರ್ಜುನನ ಭಾವ ಅಡಗಿದೆ. ಜನ-ಅರ್ದನ\nಅಂದರೆ ಜನರನ್ನು ನಾಶ ಮಾಡುವವ! ಇಲ್ಲಿ ಜನ ಅಂದರೆ ದುರ್ಜನ. ಜನಾರ್ದನ ಅಂದರೆ ದುರ್ಜನ ನಾಶಕ.\n“ದುಷ್ಟ ನಿಗ್ರಹಕ್ಕಾಗಿ ಅವತರಿಸಿದ ನೀನು, ನನ್ನಿಂದ ಈ ಕಾರ್ಯವನ್ನು ಮಾಡಿಸುತ್ತಿದ್ದೀಯ. ಆದರೆ ಇಲ್ಲಿ\nಸೇರಿರುವರೆಲ್ಲಾ ದುರ್ಜನರಲ್ಲ. ಹೀಗಿರುವಾಗ ಅವರನ್ನು ಕೊಲ್ಲುವ ಕರ್ಮ ಶ್ರೇಷ್ಠ ಹೇಗಾದೀತು? ಜನನ\n\nಮುಕ್ತಗೊಳಿಸಿ ಮೋಕ್ಷವನ್ನು ಕರುಣಿಸುವ ನೀನು, ನನ್ನಿಂದ ಗುರು ಹಿರಿಯರನ್ನು ಕೊಲ್ಲುವ ಈ ಘೋರ ಕರ್ಮವನ್ನು\nಏಕೆ ಮಾಡಿಸುತ್ತಿರುವೆ?”. ಎನ್ನುವುದು ಅರ್ಜುನನ ಪ್ರಶ್ನೆ. ಶ್ಲೋಕದ ಕೊನೆಯಲ್ಲಿ *ಕೇಶವ' ಎನ್ನುವ\nನಾಮವಿಶೇಷಣ ಅರ್ಜುನನ ಶರಣಾಗತಿಯನ್ನು ಸೂಚಿಸುತ್ತದೆ. ಕಾ-ಈಶ-ವ-ಕೇಶವ; ಇಲ್ಲಿ 'ಕಾ' ಎಂದರೆ\nಸೃಷ್ಟಿಗೆ ಕಾರಣವಾಗಿರುವ ಚತುರ್ಮುಖ ಬ್ರಹ್ಮ ; ಈಶ ಎಂದರೆ ಸಂಹಾರಕ್ಕೆ ಕಾರಣವಾಗಿರುವ ಶಂಕರ. ಕೇಶವ\nಅಂದರೆ ಸೃಷ್ಟಿ-ಸಂಹಾರಕ್ಕೆ ಕಾರಣವಾಗಿರುವ ಬ್ರಹ್ಮಶಕ್ತಿ ಮತ್ತು ಶಿವಶಕ್ತಿಯನ್ನೊಳಗೊಂಡ ಪರಶಕ್ತಿ. “ಸೃಷ್ಟಿ-ಸ್ಥಿತಿ-\nಸಂಹಾರ-ಮೋಕ್ಷಗಳಿಗೆ ಕಾರಣನಾದ ನೀನು ನನ್ನನ್ನು ಈ ಗೊಂದಲದಿಂದ ಪಾರು ಮಾಡು” ಎಂದು ಅರ್ಜುನ\nಶ್ರೀಕೃಷ್ಣನಲ್ಲಿ ಶರಣಾಗಿ ಬೇಡುತ್ತಾನೆ.",
  "3.2": "ವ್ಯಾಮಿಶ್ರೇಣ ಇವ ವಾಕ್ಯೇನ ಬುದ್ಧಿಮ್‌ ಮೋಹಯಸಿ ಇವ ಮೇ |\n\nತತ್‌... ಏಕಮ್‌ ವದ ನಿಶ್ಚಿತ್ಯ ಯೇನ ಶ್ರೇಯಃ ಅಹಮ್‌ ಅಪ್ಲುಯಾಮ್‌-ಇಬ್ಬಗೆಯ ಮಾತಿನಿಂದ ನನ್ನ\nನಿರ್ಧಾರಶಕ್ತಿಯನ್ನು ಗೊಂದಲಕ್ಕೀಡುಮಾಡುವಂತಿದೆ. ಆದ್ದರಿಂದ, ಒಂದನ್ನು ನಿರ್ಧರಿಸಿ ಹೇಳು: ಯಾವುದರಿಂದ\nನಾನು ಒಳಿತನ್ನು ಪಡೆದೇನು?\n\nಇಲ್ಲಿ 'ವ್ಯಾಮಿಶ್ರೇಣ' ಎಂದರೆ ವಿರೋಧಾಭಾಸ. “ಈ ರೀತಿ ಇಬ್ಬಗೆಯ\nಮಾತಿನಿಂದ ನನಗೆ ಯಾವುದು ಸರಿ-ಯಾವುದು ತಪ್ಪು ಎನ್ನುವ ತೀರ್ಮಾನ ಬರುತ್ತಿಲ್ಲ, ಹಾಗೂ ಅದನ್ನು\nತಿಳಿಯುವ ಶಕ್ತಿ ನನ್ನಲ್ಲಿಲ್ಲ. ನಿನ್ನ ಅಭಿಪ್ರಾಯವನ್ನು ನಾನು ಗ್ರಹಿಸಲಾರೆ. ಯಾವ ದಾರಿಯಲ್ಲಿ ನಡೆದರೆ ನಾನು\nಶ್ರೇಯಸ್ಸನ್ನು ಪಡೆದೇನು? ನನ್ನ ಬದುಕು ಸಾರ್ಥಕವಾಗುವ ನಿಶ್ಚಿತ ದಾರಿಯನ್ನು ಹೇಳು” ಎಂದು ಕೃಷ್ಣನಲ್ಲಿ\nಅರ್ಜುನ ಕೇಳಿಕೊಳ್ಳುತ್ತಾನೆ.",
  "3.3": "ಭಗವಾನುವಾಚ-ಭಗವಂತ ನುಡಿದನು:\n\nಲೋಕೇ ಅಸ್ಮಿನ್‌ ದ್ವಿ ವಿಧಾ ನಿಷ್ಠಾ ಪುರಾ ಪ್ರೋಕ್ತಾ ಮಯಾ ಅನಘ |\n\nಜ್ಞಾನಯೋಗೇನ ಸಾಂಖ್ಯಾನಾಮ್‌ ಕರ್ಮಯೋಗೇನ ಯೋಗಿನಾಮ್‌--ಓ ಅನಘಾ, ಈ ಲೋಕದಲ್ಲಿ ಎರಡು\nಬಗೆಯ ಇರವನ್ನು (ಮುಕ್ತಿಯನ್ನು) ನಾನು ಹಿಂದೆ ಹೇಳಿರುವೆ: ಜ್ಞಾನಮಾರ್ಗಿಗಳಿಗೆ ಜ್ಞಾನ ಪ್ರಧಾನವಾದ\nಸಾಧನೆಯಿಂದ; ಕರ್ಮಮಾರ್ಗಿಗಳಿಗೆ ಕರ್ಮಪ್ರಧಾನವಾದ ಸಾಧನೆಯಿಂದ.\n\nಈ ಹಿಂದೆ ಜ್ಞಾನಮಾರ್ಗ ಮತ್ತು ಕರ್ಮಮಾರ್ಗದ ಬಗ್ಗೆ ಹೇಳಿದ್ದ ಕೃಷ್ಣ, ಯಾವ ನೆಲೆಯಲ್ಲಿ ಯಾವ ಸ್ತರದಲ್ಲಿ\nಯಾವುದು ಮುಖ್ಯ ಎನ್ನುವ ವಿಚಾರವನ್ನು ಇಲ್ಲಿ ವಿವರಿಸುತ್ತಾನೆ. ಕರ್ಮಯೋಗದ ಬಗ್ಗೆ ವಿಶೇಷ ವಿವರಣೆ ಇಲ್ಲಿಂದ\nಆರಂಭವಾಗುತ್ತದೆ.\n\nಈ ಶ್ಲೋಕದಲ್ಲಿ 'ನಿಷ್ಠಾ' ಎನ್ನುವ ಪದ ಬಳಕೆಯಾಗಿದೆ. ಇಲ್ಲಿ 'ನಿಷ್ಠಾ' ಎಂದರೆ ಜೀವನದ ನಡೆ ಅಥವಾ ಕೊನೇಯ\nಸ್ಥಿತಿ-ಅದೇ 'ಮೋಕ್ಷ'. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಸಾಧಕರಲ್ಲಿ ಎರಡು ವಿಧ -ಸಾಂಖ್ಯರು ಮತ್ತು ಯೋಗಿಗಳು\" ಎಂದು.\nಇಲ್ಲಿ ಸಾಂಖ್ಯರು ಎಂದರೆ ಜ್ಞಾನಮಾರ್ಗದಲ್ಲಿ ಸಾಧನೆ ಮಾಡುವವರು. ಯೋಗಿಗಳು ಎಂದರೆ ಕರ್ಮಸಾಧನೆಯ\nಮೂಲಕ ಸಾಧನೆ ಮಾಡುವವರು.\n\nಈ ಶ್ಲೋಕವನ್ನು ಮೇಲ್ನೋಟದಲ್ಲಿ ನೋಡಿದರೆ: “ಜ್ಞಾನದ ಸಾಧಕರು ಜ್ಞಾನ ಮಾರ್ಗದಲ್ಲಿ ಹೋಗಬೇಕು, ಕರ್ಮದ\nಮೂಲಕ ಸಾಧನೆ ಮಾಡುವವರು ಕರ್ಮದ ದಾರಿಯಲ್ಲಿ ಹೋಗಬೇಕು” ಎಂದು ಹೇಳಿದಂತೆ ಕಾಣಿಸುತ್ತದೆ. ಇಲ್ಲಿ\nಅರ್ಜುನ ಕರ್ಮದ ಮೂಲಕ ಸಾಧನೆ ಮಾಡಬೇಕಾದವ, ಆದ್ದರಿಂದ ಕೃಷ್ಣ ಆತನಲ್ಲಿ ಯುದ್ಧ ಮಾಡು ಎಂದು\nಹೇಳಿದ ಎನ್ನು ವಂತೆ ಕಾಣುತ್ತದೆ. ಆದರೆ ಅದು ನಿಜವಾದ ಅರ್ಥವಲ್ಲ. ನಿಮಗೆ ತಿಳಿದಂತೆ ಅರ್ಜುನ ಆ ಕಾಲದ\nಮಹಾಜ್ಞಾನಿಗಳಲ್ಲಿ ಒಬ್ಬ. ಹಾಗಿರುವಾಗ ನಾವು ಈ ರೀತಿ ಮೇಲ್ನೊ ೀಟದ ಅರ್ಥವನ್ನು ಈ ಶ್ಲೋಕಕ್ಕೆ\nಅರ್ಥೈಸಬಾರದು. ಇಲ್ಲಿ ಆಳವಾದ ಚಿಂತನೆ ಅಗತ್ಯ.\n\nಶಾಸ್ತ್ರಗಳಲ್ಲಿ ಹೇಳುವಂತೆ ಜ್ಞಾನದಿಂದ ಮಾತ್ರ ಮೋಕ್ಷಕ್ಕೆ ಹೋಗಲು ಸಾಧ್ಯ. ಮೋಕ್ಷಕ್ಕೆ ಬೇರೆ ಮಾರ್ಗವೇ ಇಲ್ಲ.\nಅಂದಮೇಲೆ ಮೋಕ್ಷ ಸಾಧನೆಗೆ ಜ್ಞಾನ ಬೇಕೇಬೇಕು. ಕರ್ಮವಿರುವುದು ಜ್ಞಾನಕ್ಕಾಗಿ. ಜ್ಞಾನಕ್ಕೆ ಪೂರಕವಲ್ಲದ\nಕರ್ಮ-ಕರ್ಮವಲ್ಲ. ಬೆಳಗಿನಿಂದ ಸಂಜೆಯ ತನಕ ಜಪ ಮಣಿ ಹಿಡಿದು ಮಡಿ-ಮಡಿ ಎಂದು ಕುಳಿತರೆ ಅದು\nನಮ್ಮನ್ನು ಎತ್ತರಕ್ಕೆ ಕೊಂಡೊಯ್ಯಲಾರದು. ಸಾವು ಏನೇ ಕರ್ಮ ಮಾಡುವುದಿದ್ದರೂ ಅದನ್ನು ತಿಳಿದು\nಮಾಡಬೇಕು. ಮಾಡುವ ಕರ್ಮ ಜ್ಞಾನಕ್ಕೆ ಪೂರಕವಾಗಿರಬೇಕು. ಆದ್ದರಿಂದ ಬರೀ ಜ್ಞಾನಯೋಗವೆಂದಾಗಲೀ,\nಬರೀ ಕರ್ಮಯೋಗವೆಂದಾಗಲೀ ಇಲ್ಲ. ಕರ್ಮವಿಲ್ಲದೆ ಜ್ಞಾನವಿಲ್ಲ, ಜ್ಞಾನವಿಲ್ಲದೆ ಕರ್ಮವಿಲ್ಲ. ಛಾಂದೊಗ್ಯ\nಉಪನಿಷತ್ತಿನಲ್ಲಿ. ಹೇಳುವಂತೆ: \"ಯದೇವ ವಿದ್ಯಯಾ ಕರೋತಿ ಶ್ರದ್ಧೆಯ ಉಪನಿಷದಾ, ತದೇವ\nವೀರ್ಯವತ್ತರಂಭವತಿ , ವಿಜ್ಞಾನಂಯಜ್ಞಾಂತನುತೇ\". ಅಂದರೆ “ನೀನು ಏನುನ್ನು ಮಾಡಿದರೂ ತಿಳಿದು\nಮಾಡು. ಜ್ಞಾನ ಪೂರ್ವಕವಾಗಿ ಮಾಡಿದ ಕರ್ಮ ಸಫಲ. ಇಲ್ಲದಿದ್ದರೆ ಅದು ವ್ಯರ್ಥ”. ಮಾಡುವ ಕರ್ಮವನ್ನು\nಏತಕ್ಕಾಗಿ ಮಾಡುತ್ತಿದ್ದೇವೆ, ಮಾಡುವುದರ ಫಲವೇನು, ಮಾಡುವುದು ಹೇಗೆ-ಎನ್ನುವುದು ಗೊತ್ತಿರಬೇಕು.\nಅಜ್ಞಾನದಿಂದ ಮಾಡುವ ಕರ್ಮ ವ್ಯರ್ಥವಾಗುತ್ತದೆ. ಇಲ್ಲಿ ಕೃಷ್ಣ ಹೇಳಿರುವುದು ಒಂದು ಕರ್ಮಪ್ರದವಾದ\nಮಾರ್ಗ(ಜನಕಾದಿಗಳಂತೆ) ಹಾಗೂ ಇನ್ನೊಂದು ಜ್ಞಾನಪ್ರದವಾದ ಮಾರ್ಗ(ಸನಕಾದಿಗಳಂತೆ).",
  "3.4": "ನ ಕರ್ಮಣಾಮ್‌ ಅನಾರಂಭಾತ್‌ ನೈಷ್ಕರ್ಮ್ಯಂ ಪುರುಷಃ ಅಶ್ನು ತೇ।\nನಚ ಸಂನ್ಯಸನಾತ್‌ ಏವ ಸಿದ್ಧಿಮ್‌ ಸಮಧಿಗಚ್ಛತಿ--ಕರ್ಮಗಳಲ್ಲಿ ತೊಡಗದೇ ಇರುವುದರಿಂದ ಸಾಧಕ\n\nಕರ್ಮಗಳಿಂದ ಬಿಡುಗಡೆ ಹೊಂದುವುದಿಲ್ಲ. ಕರ್ಮ ಫಲವನ್ನು ತೊರೆದ ಮಾತ್ರಕ್ಕೆ\n\nಸಿದ್ಧಿ ಪಡೆಯುವುದಿಲ್ಲ.\nಶಾಸ್ತ್ರಗಳಲ್ಲಿ ಹೇಳುವಂತೆ 'ಕರ್ಮ ಬಂಧನದ ದಾರಿ ಹಾಗೂ ಜ್ಞಾನ ಬಿಡುಗಡೆಯ ದಾರಿ'. ಆದರೆ ಕೃಷ್ಣ ಹೇಳಿದ -\nಮೋಕ್ಷಕ್ಕೆ ಜ್ಞಾನಪ್ರದವಾದ ಮತ್ತು ಕರ್ಮಪ್ರದವಾದ ಎರಡು ಮಾರ್ಗಗಳಿವೆ ಎಂದು. ಇಲ್ಲಿ ಅದರ ವಿವರಣೆ\nಕೊಡುತ್ತಾನೆ ಕೃಷ್ಣ. ಮೋಕ್ಷ ನಿಷ್ಕರ್ಮದಿಂದ ಪಡೆಯುವಂತಾದ್ದು; ಕರ್ಮ-ಬಂಧಕ ಅನ್ನುವುದಾದರೆ, ಒಂದು\nಶರೀರದಲ್ಲಿ ಜೀವ ಏನೂ ಕರ್ಮ ಮಾಡದೇ ಇರಲು ಸಾಧ್ಯವೇ ಇಲ್ಲ. ದೇಹ ಬಂದ ಮೇಲೆ ಕರ್ಮ ಕ್ರಿಯೆ ನಡೆದೇ\nನಡೆಯುತ್ತದೆ. ಕರ್ಮ ಮಾಡುವುದನ್ನು ಬಿಟ್ಟ ತಕ್ಷಣ ಮೋಕ್ಷ ದೊರೆಯದು. ಮೂಲತಃ ಕರ್ಮವನ್ನು\nತೊರೆಯುವುದೂ ಸಾಧ್ಯವಿಲ್ಲ. ಜ್ಞಾನಕ್ಕೆ ಪೂರಕವಲ್ಲದ ಯಾಂತ್ರಿಕ ಕರ್ಮ ಬಂಧಕ. ಜ್ಞಾನಕ್ಕೆ ಪೂರಕವಾದ\nಕರ್ಮ ಎಂದೂ ಬಂಧಕವಲ್ಲ. ಕರ್ಮದ ಫಲವನ್ನು ಬಯಸದೇ ಇದ್ದ ತಕ್ಷಣ ಯಾವ ಸಿದ್ಧಿಯೂ ಆಗದು. ಕೇವಲ\nಕರ್ಮತ್ಯಾಗ ಮಾಡುವುದರಿಂದ ಎಂದೂ ಸಿದ್ಧಿ ಪಡೆಯಲು ಸಾಧ್ಯವಿಲ್ಲ.",
  "3.5": "ಕಾರ್ಯತೇ ಹಿ ಅವಶಃ ಕರ್ಮ ಸರ್ವಃ ಪ್ರಕೃತಿಜೈಃ ಗುಣೈಃ--ಯಾವನೂ ಒಂದು ಕ್ಷಣ ಕೂಡಾ ಏನೂ ಮಾಡದೇ\nತೆಪ್ಪಗಿರುವುದು ಸಾಧ್ಯವಿಲ್ಲ. ಪ್ರತಿಯೊಬ್ಬನೂ ಪ್ರಕೃತಿಯ ಗುಣಗಳಿಂದ ಅರಿವಿಲ್ಲದೆಯೇ (ಭಗವಂತನ\nಅಧೀನವಾಗಿ) ಕರ್ಮ ಮಾಡುತ್ತಾನೆ.\n\nಕರ್ಮತ್ಯಾಗದಿಂದ ಸಿದ್ಧಿ ಸಿಗದು. ಅಷ್ಟೇ ಅಲ್ಲ, ಕರ್ಮತ್ಯಾಗ ಮಾಡುವುದು ಸಾಧ್ಯವೇ ಇಲ್ಲ. ನಮ್ಮ ಅನ್ನಮಯ\nಮತ್ತು ಪ್ರಾಣಮಯಕೋಶ ನಿರಂತರ ಕಾರ್ಯ ನಿರ್ವಹಿಸುತ್ತಿರುತ್ತವೆ. ಬದುಕಿರುವಾಗ ನಿಷ್ಕ್ರೀಯರಾಗಿರುವುದು\nಅಸಾಧ್ಯ. ಯಾವ ಕಾಲದಲ್ಲೂ ಕೂಡಾ ಒಂದು ಕ್ಷಣವೂ ನಿಷ್ಕ್ರೀಯನಾಗಿ ಇರುವುದು ಯಾರಿಗೂ ಸಾಧ್ಯವಿಲ್ಲ.\n\"ಕಾರ್ಯತೇ ಹಿ ಅವಶಃ”-ದೇಹದ ಒಳಗಿರುವ ಜೀವನಲ್ಲಿ ಆತನ ದೇಹದ ಮೂಲಕ, ಮನಸ್ಸಿನ ಮೂಲಕ,\nಮಾತಿನ ಮೂಲಕ-ಕೆಲಸ ಮಾಡಿಸಲ್ಪಡುತ್ತದೆ. ಅದು ಜೀವನ ಸ್ವಾಧೀನದಲ್ಲಿರುವುದಿಲ್ಲ. ಅದು ಭಗವಂತನ ವಶ.\nಇಡೀ ವಿಶ್ವವೇ ಪ್ರಕೃತಿಯಿಂದ ಸೃಷ್ಠಿಯಾಗಿದೆ. ಅದರ ಮೂಲ ದ್ರವ್ಯ ಸತ್ವ-ರಜಸ್ಸು-ತಮಸ್ಸು. ಜೀವಕ್ಕೆ ಅದರದ್ದೇ\nಆದ ಸ್ವಭಾವವಿರುತ್ತದೆ. ಅದಕ್ಕನುಗುಣವಾಗಿ ಪ್ರಕೃತಿಯ ಈ ತ್ರಿಗುಣಗಳ ಪ್ರಭಾವ ನಮ್ಮ ಮೇಲಾಗುತ್ತಿರುತ್ತದೆ.\nಆದ್ದರಿಂದ ನಿಷ್ಕ ಯತೆ ಎನ್ನುವುದು ಅರ್ಥಶೂನ್ಯ. ನಾವು ಜೀವನದಲ್ಲಿ ನಮ್ಮನ್ನು ನಾವು ತೊಡಗಿಸಿಕೊಳ್ಳಬೇಕು.\nಕರ್ತವ್ಯ ಶೀಲರಾಗಬೇಕು. ಅದರೊಂದಿಗೆ ಮಾನಸಿಕವಾಗಿ ಐಹಿಕ ಪ್ರಪಂಚದಿಂದ ಆಚೆಗಿನ ಸತ್ಯದ ಕಡೆ ನಮ್ಮ\nಮನಸ್ಸು ಜಾಗೃತವಾಗಿರಬೇಕು. ಈ ಎಚ್ಚರದಿಂದ ಎಲ್ಲಾ ಕರ್ತವ್ಯ ಕರ್ಮಗಳನ್ನು ಮಾಡಬೇಕು. ನಿಷ್ಕ್ರೀಯತೆ\nವೇದಾಂತವಲ್ಲ-ಕರ್ತವ್ಯಚ್ಯುತಿ ಅಧ್ಯಾತ್ಮವಲ್ಲ. ಭಗವಂತನ ಪ್ರಜ್ಞೆಯೊಂದಿಗೆ",
  "3.6": "ಕರ್ಮೇಂದ್ರಿಯಾಣಿ ಸಂಯಮ್ಯ ಯಃ ಆಸ್ತೇ ಮನಸಾ ಚರನ್‌ |\nಇಂದ್ರಿಯ ಅರ್ಥಾನ್‌ ವಿಮೂಢ ಆತ್ಮಾ ಮಿಥ್ಯಾ ಆಚಾರ: ಸಃ ಉಚ್ಯತೇ- ಕರ್ಮೇಂದ್ರಿಯಗಳನ್ನು ಅದುಮಿಟ್ಟು ಸ;\nಮನಸ್ಸಿ ನಿಂದಲೇ ಇಂದ್ರಿಯ ವಿಷಯಗಳ ಕನಸು ಕಾಣುವ ತಿಳಿಗೇಡಿ ಡಂಭಾಚಾರಿ ಎನಿಸುತ್ತಾನೆ.\n\nಈ ಶ್ಲೋಕದಲ್ಲಿ ಕೃಷ್ಣ ಒಂದು ಮುಖ್ಯವಾದ ವಿಚಾರವನ್ನು ಹೇಳಿದ್ದಾನೆ. ಸಾಮಾನ್ಯವಾಗಿ ಇಂದಿನ ಪ್ರಪಂಚದಲ್ಲಿ\nಹೊರಗಿನ ವೇಷಕ್ಕೆ ಹೆಚ್ಚು ಪ್ರಾಧಾನ್ಯತೆ ಕೊಡುತ್ತಿರುವುದನ್ನು ನಾವು ಕಾಣುತ್ತೇವೆ. ಮನಸ್ಸಿನಲ್ಲಿ ಎಲ್ಲಾ ಆಸೆ\nಇಟ್ಟುಕೊಂಡು, ಯಾವುದೋ ಭಯದಿಂದ ಹೊರನೋಟಕ್ಕೆ ಸದಾಚಾರಸಂಪನ್ನರಂತೆ ಬದುಕುವವರಿದ್ದಾರೆ. ಕೃಷ್ಣ\nಇದನ್ನು ಕಪಟ ಧಾರ್ಮಿಕತೆ ಎನ್ನುತ್ತಾನೆ. ನಾವು ಮೊದಲು ನಮ್ಮ ಆತ್ಮಸಾಕ್ಷಿಗೆ ವಂಚನೆ ಮಾಡದೇ\nಬದುಕಬೇಕು. ಹೊರಗಿನ ಆಚಾರಕ್ಕಿಂತ ಮೊದಲು ಒಳಗಿನ ಆಚಾರಶುದ್ಧಿ ಮುಖ್ಯ. ಇದಿಲ್ಲದಿದ್ದರೆ ಎಂದೂ\nಉದ್ಧಾರವಿಲ್ಲ. ಕರ್ಮೇಂದ್ರಿಯಗಳನ್ನು ಅದುಮಿಟ್ಟು, ಮನಸ್ಸಿನಿಂದಲೇ ಇಂದ್ರಿಯ ವಿಷಯಗಳ ಕನಸು ಕಾಣುವ\n\nತಿಳಿಗೇಡಿ ಡಂಭಾಚಾರಿ ಎನಿಸುತ್ತಾನೆ ಎಂದಿದ್ದಾನೆ ಕೃಷ್ಣ.\n",
  "3.7": "ಯಃ ತು ಇಂದ್ರಿಯಾಣಿ ಮನಸಾ ನಿಯಮ್ಯ ಆರಭತೇ ಅರ್ಜುನ |\n\nಕರ್ಮ ಇಂದ್ರಿಯೈಃ ಕರ್ಮಯೋಗಮ್‌ ಅಸಕ್ತಃ ಸಃ ವಿಶಿಷ್ಯತೇ- ಓ ಅರ್ಜುನಾ, ಇಂದ್ರಿಯಗಳನ್ನು\nಮನೋಬಲದಿಂದ ಗೆದ್ದು, ಫಲದ ನಂಟು ತೊರೆದು, ಇಂದ್ರಿಯಗಳ ಮೂಲಕ ಸಾಧನೆಯಲ್ಲಿ ತೊಡಗುವವನು\nಮಿಗಿಲಾದವನು.\n\nಮನಸ್ಸು ಸ್ವಚ್ಛವಾಗಿದ್ದು, ಇಂದ್ರಿಯಗಳ ಮೇಲೆ ಮಾನಸಿಕ ಕಡಿವಾಣ ಗಟ್ಟಿಯಿದ್ದಾಗ- ಕರ್ಮೆಂದ್ರಿಯದಿಂದ\nಮಾಡುವ ಸಾಧನೆ ಕರ್ಮಯೋಗವಾಗುತ್ತದೆ. ಇದು ಶುದ್ಧ ಅಧ್ಯಾತ್ಮ ಸಾಧನೆ. ಈ ಸ್ಥಿತಿಯಲ್ಲಿ ಇಂದ್ರಿಯಗಳು\nದಾರಿ ತಪ್ಪುವುದಿಲ್ಲ. ತನ್ನ ಜೀವ ಸ್ವರೂಪದ ಸ್ವಭಾವಕ್ಕನುಗುಣವಾಗಿ ಚಿತ್ತ ಶುದ್ಧಿಯಿಂದ ಮಾಡುವ ಕರ್ಮ\nನಿಜವಾದ ಅಧ್ಯಾತ್ಮ ಸಾಧನೆ. ಈ ರೀತಿಯ ಸಾಧನೆಯಲ್ಲಿ ತೊಡಗುವವನು ಶ್ರೇಷ್ಠನೆನಿಸುತ್ತಾನೆ. ಇಂತವರು\nಒಳಗೊಂದು-ಹೊರಗೊಂದು ಆಗಿರದೇ, ಮನೋಬಲದಿಂದ ಇಂದ್ರಿಯಗಳನ್ನು ಗೆದ್ದು, ಫಲದ ನಂಟನ್ನು\nತೊರೆದು, ಎತ್ತರಕ್ಕೇರುತ್ತಾರೆ.\n",
  "3.8": "ನಿಯತಮ್‌ ಕುರು ಕರ್ಮ ತ್ವಮ್‌ ಕರ್ಮ ಜ್ಯಾಯಃ ಹಿ ಅಕರ್ಮಣಃ |\nಶರೀರ ಯಾತ್ರಾ ಅಪಿ ಚ ತೇ ನ ಪ್ರಸಿದ್ಧೇತ್‌ ಅಕರ್ಮಣಃ -ನಿನ್ನ ಪಾಲಿನ ಕರ್ಮ ನೀನು ಮಾಡು.\nನಿಷ್ಕ ೀಯತೆಗಿಂತ ಕರ್ಮ ಮೇಲಲ್ಲವೇ ? ನಿಷ್ಕ ೀಯನಾದರೆ ನಿನ್ನ ಬಾಳ ಬಂಡಿಯ ಪಯಣವು ಸಾಗದು.\n\nಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: 'ನೀನು ನಿನ್ನ ಜೀವ ಸ್ವಭಾವಕ್ಕೆ ಅನುಗುಣವಾದ, ಜ್ಞಾನಕ್ಕೆ ಪೂರಕವಾದ ನಿಯತ ಕರ್ಮವನ್ನು\nಮಾಡು' ಎಂದು. ಇಲ್ಲಿ ಅರ್ಜುನನನ್ನು ನೋಡಿದರೆ, ಆತನ ಜೀವ ಸ್ವಭಾವ ಅನ್ಯಾಯದ ವಿರುದ್ಧ ಹೋರಾಡಿ\nದೇಶದ ಪ್ರಜೆಗಳ ರಕ್ಷಣೆ ಮಾಡುವ ಕ್ಷತ್ರಿಯ ಸ್ವಭಾವ. ಅದನ್ನು ಬಿಟ್ಟು, ದೇಶದಲ್ಲಿ ಅನ್ಯಾಯ\nತಾಂಡವವಾಡುತ್ತಿರುವಾಗ, ಜ್ಞಾನ ಮಿಗಿಲೆಂದು ತಪಸ್ಸನ್ನಾಚರಿಸಿದರೆ ಅದು ನಿಜವಾದ ಯೋಗವೆನಿಸುವುದಿಲ್ಲ.\nಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ, “ಎಂದೂ ನಿಷ್ಕ್ರೀಯನಾಗಬೇಡ, ನಿನ್ನ ಕರ್ಮವನ್ನು ನೀನು ಮಾಡು, ಅದರಿಂದ ಏನು\nಸಿಕ್ಕಿತೋ ಅದನ್ನು ಅನುಭವಿಸು. ಆದರೆ ಮಾಡುವ ಕರ್ಮ ಜ್ಞಾನಕ್ಕೆ ಪೂರಕವಾಗಿರಲಿ. ಭಗವಂತನ ಎಚ್ಚರ\nಯಾವಾಗಲೂ ಇರಲಿ” ಎಂದು. “ಭಗವಂತ ಈ ಕರ್ಮವನ್ನು ನನ್ನ ಕೈಯಿಂದ ಮಾಡಿಸುತ್ತಿದ್ದಾನೆ, ಇದು\nಅವನಿಗರ್ಪಿತ' ಎನ್ನುವ ಭಾವನೆಯಿಂದ ಕರ್ಮ ಮಾಡಿದಾಗ ಯಾವ ಕರ್ಮವೂ ನಮಗೆ ಬಂಧಕವಾಗುವುದಿಲ್ಲ.\n\nನಿನ್ನ ಪಾಲಿನ ಕರ್ಮ ಮಾಡು, ಬಂದುದನುಣ್ಣು, ಹರಿಯ ಚರಣದ ಅರಿವು ತಪ್ಪದಿರಲಿ.\nಹರಿಯೇ ಪರ ದೈವತವು, ಹರಿಯೇ ಗುರು ಆಸರೆಯು, ಹರಿಯೊಬ್ಬನೆ ಜಗದ ತಾಯಿ ತಂದೆ.\n\nನಾವು ಒಂದು ದೇಹದಲ್ಲಿರುವಷ್ಟು ಕಾಲ ಕರ್ಮ ಅನಿವಾರ್ಯ. ಅಪರೋಕ್ಷ ಜ್ಞಾನ ಬಂದಾಗಲೂ ಕೂಡಾ ಕರ್ಮ\nನಿರಂತರ. ಈ ರೀತಿ ಕೃಷ್ಣ ಕರ್ಮ ಸಿದ್ಧಾಂತವನ್ನು ಈ ಶ್ಲೋಕದ ಮುಖೇನ ನಮ್ಮ ಮುಂದೆ ಬಿಚ್ಚಿಟ್ಟಿದ್ದಾನೆ.\n\nಇಲ್ಲಿ ಒಂದು ವಿಷಯವನ್ನು ನಾವು ಸರಿಯಾಗಿ ಅರ್ಥ ಮಾಡಿಕೊಳ್ಳಬೇಕು. ಶಾಸ್ತ್ರಗಳು ಹೇಳುವ ಪ್ರಕಾರ ಕರ್ಮ\nಬಂಧಕ. ಪುನಃ ಕರ್ಮ ಮಾಡುವುದರಿಂದ ನಾವು ಕರ್ಮ ಚಕ್ರದಲ್ಲಿ ಸಿಲುಕುತ್ತೇವೆ. ಆದರೆ ಇಲ್ಲಿ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ-\nಕರ್ಮ ಅನಿವಾರ್ಯ ಎಂದು. ಹಾಗಿದ್ದರೆ ಮೋಕ್ಷದ ಮಾರ್ಗ ಯಾವುದು? ನಮ್ಮ ಈ ಪ್ರಶ್ನೆಗೆ ಮುಂದಿನ\nಶ್ಲೋಕದಲ್ಲಿ ಸ್ಪಷ್ಟ ಉತ್ತರವಿದೆ.\n",
  "3.9": "ಯಜ್ಞಾ ಅರ್ಥಾತ್‌ ಕರ್ಮಣಃ ಅನ್ಯತ್ರ ಲೋಕಃ ಅಯಮ್‌ ಕರ್ಮ ಬಂಧನಃ |\nತತ್‌ ಅರ್ಥಮ್‌ ಕರ್ಮ ಕೌಂತೇಯ ಮುಕ್ತಸಂಗಃ ಸಮಾಚರ-- ಭಗವಂತನ ಪೂಜಾರೂಪವಾದ ಇಂತಹ\n\nಕರ್ಮಕ್ಕಿಂತ ಬೇರೆಯಾದ ನಡೆಯಲ್ಲಿ ಮಾತ್ರ ಸಾಧಕ ಕರ್ಮದ ತಟ್ಟಿಗೆ ಸಿಲುಕುತ್ತಾನೆ. ಓ ಕೌಂತೇಯಾ, ಫಲದ\nನಂಟು ತೊರೆದು, ಭಗವಂತನ ಪೂಜೆಯೆಂದು ಕರ್ಮ ಮಾಡು.\n\nಈ ಲೋಕ ಕರ್ಮದ ಬಂಧನಕ್ಕೆ ಒಳಗಾಗಿದೆ. ಆದರೆ ಎಲ್ಲಾ ಕರ್ಮವೂ ಬಂಧಕ ಅಲ್ಲ. ತಿಳಿದು ಮಾಡುವ ಕರ್ಮ\nಎಂದೂ ಬಂಧಕವಾಗುವುದಿಲ್ಲ. ನಾವು ಮಾಡುವ ಕರ್ಮವನ್ನು ಭಗವಂತನ ಪ್ರಜ್ಞೆಯಿಂದ ಮಾಡಬೇಕು. ನಾವು\nಸೂತ್ರದ ಗೊಂಬೆಗಳಿದ್ದಂತೆ. ಭಗವಂತ ಸೂತ್ರದಾರ. ಈ ಎಚ್ಚರದಿಂದ ನಾವು ಕರ್ಮ ಮಾಡಿದಾಗ ನಮ್ಮ\nಪ್ರತಿಯೊಂದು ಕರ್ಮವೂ ಕೂಡಾ ಯಜ್ಞವಾಗುತ್ತದೆ. ಉದಾಹರಣೆಗೆ ನಾವು ಉಸಿರಾಡುತ್ತೇವೆ. ಹೊರಗಿನಿಂದ\nಆಮ್ಲಜನಕವನ್ನು ಹೀರಿ ಕಾರ್ಬನ್‌ ಡೈ ಆಕ್ಸೈಡನ್ನು ಹೊರ ಹಾಕುತ್ತೇವೆ. ನಮ್ಮೊಳಗಿರುವ ಆ ವಿಶೇಷ ಯಂತ್ರದ\nಕಲ್ಪನೆ ಕೂಡಾ ನಮಗಿರುವುದಿಲ್ಲ. ನಮಗೆ ಅರಿವಿಲ್ಲದಂತೆ ಈ ಕ್ರಿಯೆ ನಡೆಯುತ್ತಿರುತ್ತದೆ. ನಾವು ಬಿಟ್ಟ\nಗಾಳಿಯನ್ನು ಗಿಡಗಳು ಸೇವಿಸಿ ನಮಗೆ ಬೇಕಾದ ಆಮ್ಲಜನಕವನ್ನು ಕೊಡುತ್ತವೆ. ಇದೆಲ್ಲವೂ ಆ ಭಗವಂತನ\nವ್ಯವಸ್ಥೆ. ಈ ಕಾರಣಕ್ಕಾಗಿ ಭಾರತೀಯರು ಅತಿಹೆಚ್ಚು ಆಮ್ಲಜನಕವನ್ನು ಕೊಡುವ ಅಶ್ವತ್ಥವೃಕ್ಷವನ್ನು\nಪೂಜಿಸುತ್ತಾರೆ. ಆ ವೃಕ್ಷದಲ್ಲಿ ಭಗವಂತನ ವಿಶೇಷ ವಿಭೂತಿ ಅಡಗಿದೆ. ಈ ರೀತಿ ನಾವು ನಮ್ಮ ಪ್ರತಿಯೊಂದು\nಕಾರ್ಯದಲ್ಲೂ ಭಗವಂತನ ಹಿರಿಮೆಯನ್ನು ತಿಳಿದಾಗ, ನಾವು ಮಾಡುವ ಕರ್ಮ-ಕರ್ಮಯೋಗವಾಗುತ್ತದೆ.\nಹಾಗೂ ಅದು ಎಂದೂ ಬಂಧಕವಾಗುವುದಿಲ್ಲ.\n\nಇಲ್ಲಿ ಬಳಕೆಯಾದ 'ಯಜ್ಞ' ಪದದ ಅರ್ಥ 'ಯಜ-ದೇವ-ಪೂಜಾ' ಅಂದರೆ ದೇವರ ಪೂಜೆ ಎಂದರ್ಥ. ದೇವರನ್ನು\nಕೂಡಾ ಯಜ್ಞ ಎಂದು ಕರೆಯುತ್ತಾರೆ. ಆದ್ದರಿಂದ ಕೇವಲ ಅಗ್ನಿ ಮುಖದಲ್ಲಿ ಮಾಡುವ ಪೂಜೆ ಮಾತ್ರ ಯಜ್ಞವಲ್ಲ.\nನಮ್ಮ ಪ್ರತಿಯೊಂದು ಕರ್ಮವನ್ನು ಭಗವತ್ರಜ್ಞೆಯಿಂದ ಮಾಡಿದಾಗ ಅದು ಯಜ್ಞವಾಗುತ್ತದೆ. ಇಲ್ಲಿ ನಾವು\nಬಿಡಬೇಕಾದದ್ದು ಕರ್ಮವನ್ನಲ್ಲ, ಬದಲಿಗೆ ನಾವು ಕರ್ಮದ ಬಗ್ಗೆ ಇರುವ ನಮ್ಮ ಭಾವನೆಯನ್ನು ಬದಲಿಸಿ\nಕೊಳ್ಳಬೇಕು ಅಷ್ಟೆ. ಕರ್ಮ ಎಂದರೆ 'ಕರ-ಮ' ಅಂದರೆ ಭಗವಂತನ ರಾಜ್ಯದ ಪ್ರಜೆಗಳಾದ ನಾವು ಆತನಿಗೆ\nಸಲ್ಲಿಸುವ 'ಕರ' ಅಥವಾ ಕಂದಾಯವೇ ಕರ್ಮ. ಭಗವಂತ ಎಂದೂ ದುಡ್ಡಿನ ಕಂದಾಯವನ್ನು ಪಡೆಯುವುದಿಲ್ಲ.\nಆತನ ಕರ ಸಂದಾಯವನ್ನು ನಾವು- ನಮ್ಮನ್ನು ಸಮಾಜ ಕ್ರಿಯೆಯಲ್ಲಿ ತೊಡಗಿಸಿಕೊಂಡು ಸಲ್ಲಿಸಬೇಕು. ಈ\nಭಾವನೆ ಬಂದಾಗ ಕರ್ಮ ಬಂಧಕವಾಗದೇ ಮೋಕ್ಷ ಮಾರ್ಗವಾಗುತ್ತದೆ.\n\nಇಲ್ಲಿ ಕೃಷ್ಣ ಅರ್ಜುನನನ್ನು 'ಕೌಂತೇಯಾ' ಎಂದು ಸಂಬೋಧಿಸಿದ್ದಾನೆ. ಈ ರೀತಿ ಇಲ್ಲಿ ಸಂಬೋಧಿಸಲು ವಿಶೇಷ\nಕಾರಣವಿದೆ. ಕುಂತಿ ಅಷ್ಟು ದೊಡ್ಡ ಮನೆತನದಲ್ಲಿ ಹುಟ್ಟಿ ಬೆಳೆದರೂ ಕೂಡಾ, ಆಕೆ ಎಂದೂ ಭೋಗದ ಆಸೆಗೆ\nಬಲಿಬಿದ್ದವಳಲ್ಲ. ತನ್ನ ಯೌವನವನ್ನು ಕಾಡಿನಲ್ಲಿ ಕಳೆದ ಆಕೆ, ತನ್ನ ಮಕ್ಕಳು ಧೈರ್ಯಗೆಟ್ಟಾಗ ಧೈರ್ಯ ತುಂಬಿದ\nಧೀರ ಮಹಿಳೆ. ಆಕೆ ಅನುಭವಿಸಿದ ಕಷ್ಟ ಅಷ್ಟಿಷ್ಟಲ್ಲ. ಆದರೆ ಆಕೆ ಕೃಷ್ಣನಲ್ಲಿ “ನನಗೆ ಕಷ್ಟವನ್ನೇ ಕೊಡು, ಏಕೆಂದರೆ\nಆಗ ನಮಗೆ ಸದಾ ನಿನ್ನೊಂದಿಗಿರುವ ಭಾಗ್ಯವಿರುತ್ತದೆ” ಎಂದಾಕೆ! ಕರ್ತವ್ಯನಿಷ್ಠೆಯನ್ನು ಜಗತ್ತಿಗೆ ತೋರಿದ ಧೀರ\nಮಹಿಳೆ ಆಕೆ. ಇಂತಹ ಮಹಾ ಮಹಿಳೆಯ ಮಗನಾದ ನಿನಗೆ ಕರ್ಮಯೋಗದ ಬಗ್ಗೆ ತಿಳಿದೇ ಇದೆ. ಎನ್ನುವ\nಧ್ವನಿಯಲ್ಲಿ ಕೃಷ್ಣ ಅರ್ಜುನನನ್ನು 'ಕೌಂತೇಯಾ' ಎಂದು ಸಂಬೋಧಿಸಿದ್ದಾನೆ.\n\nಈ ರೀತಿ ಜ್ಞಾನವನ್ನು ಮತ್ತು ಕರ್ಮವನ್ನು ಹೇಗೆ ಸಮನ್ವಯಗೊಳಿಸಿಕೊಂಡು ಬದುಕಬೇಕು ಎನ್ನುವುದನ್ನು\nಹೇಳಿದ ಕೃಷ್ಣ, ಮುಂದೆ ಅದು ಸ್ಪಷ್ಟವಾಗಿ ಅರ್ಥವಾಗುವಂತೆ ಒಂದು ಕಥೆಯ ರೂಪದಲ್ಲಿ ವಿವರಣೆಯನ್ನು\nಕೊಡುತ್ತಾನೆ. ಆ ವಿವರಣೆಯನ್ನು ಮುಂದಿನ ಶ್ಲೋಕಗಳಲ್ಲಿ ನೋಡೋಣ.",
  "3.10": "ಸಹ ಯಜ್ಞಾಃ ಪ್ರಜಾಃ ಸೃಷ್ಟ್ವಾ ಪುರಾ ಉವಾಚ ಪ್ರಜಾಪತಿಃ |\n\nಅನೇನ ಪ್ರಸವಿಷ್ಯಧ್ವಮ್‌ ಏಷ ವಃ ಅಸ್ತು ಇಷ್ಟ ಕಾಮ ಧುಕ್‌- ಹಿಂದೆ ಪ್ರಜಾಪತಿ ಭಗವಂತನ ಪೂಜಾ ರೂಪವಾದ\nಕರ್ಮದ ಜೊತೆಗೆ ಮಾನವರನ್ನು ಹುಟ್ಟಿಸಿ ಹೀಗೆ ಹೇಳಿದನು: ಇದರಿಂದ ಬೆಳವಣಿಗೆ ಹೊಂದಿ, ಇದು ನಿಮ್ಮ\nಬಯಕೆಯನ್ನು ಈಡೇರಿಸಲಿ.\n\nಹಿಂದೆ ಚತುರ್ಮುಖ- ಚಿಂತನ ಶೀಲ ಮಾನವರನ್ನು ಸೃಷ್ಠಿ ಮಾಡಿ, ಅವರಿಗಾಗಿ ಅವರು ಆಚರಿಸಬೇಕಾದ\nಯಜ್ಞವನ್ನು ಸೃಷ್ಠಿ ಮಾಡಿದ. ಹಾಗೂ ಹೇಳಿದ \" ಈ ಪೂಜಾ ವಿಧಾನದಿಂದ ಬೇಕಾದ್ದನ್ನು ಪಡೆಯಿರಿ. ಇದು ನೀವು\nಬಯಸಿದ ಅಭೀಷ್ಟವನ್ನು ಕೊಡುವ ಕಾಮದೇನು\" ಎಂದು. ಹಿಂದೆ ಹೇಳಿದಂತೆ 'ಯಜ್ಞ' ಎಂದರೆ 'ದೇವರನ್ನು\nಉಪಾಸನೆ ಮಾಡುವ ವಿಧಾನ; 'ದಾನ' ಹಾಗೂ 'ಸಂಗತೀಕರಣ' ಕೂಡಾ ಯಜ್ಞ. ದಾನ ಎನ್ನು ವುದಕ್ಕೆ ವಿಶೇಷ\nಅರ್ಥವಿದೆ. ತನ್ನಲ್ಲಿ ಬೇಕಾದಷ್ಟು ಇದ್ದು, ತನಗೆ ಬೇಡವಾದದ್ದನ್ನು ಇನ್ನೊಬ್ಬನಿಗೆ ಕೊಡುವುದು ದಾನವಲ್ಲ. ತನ್ನಲ್ಲಿ\nಎರಡು ಹೊತ್ತಿನ ಊಟವಿದ್ದು, ಇನ್ನೊಬ್ಬ ನಲ್ಲಿ ಒಂದು ಹೊತ್ತಿನ ಊಟ ಕೂಡಾ ಇಲ್ಲದಿದ್ದಾಗ, ಅವನಿಗೆ ತನ್ನಲ್ಲಿರುವ\nಊಟವನ್ನು ಕೊಟ್ಟು ಹಂಚಿ ತಿನ್ನುವುದು ನಿಜವಾದ ದಾನ. ಇನ್ನೊಬ್ಬರ ಕಷ್ಟದಲ್ಲಿ ಕರಗುವುದು ನಿಜವಾದ ದಾನ.\nಇನ್ನು ಸಂಗತೀಕರಣ ಎಂದರೆ ಜ್ಞಾನಾರ್ಜನೆಗಾಗಿ ಒಂದು ಕಡೆ ಕಲೆಯುವುದು. ಪ್ರವಚನ ಒಂದು ಸಂಗತೀಕರಣ.",
  "3.11": "ದೇವಾನ್‌ ಭಾವಯತಾ ಅನೇನ ತೇ ದೇವಾಃ ಭಾವಯಂತು ವಃ |\nಪರಸ್ಪರಮ್‌ ಭಾವಯಂತಃ ಶ್ರೇಯಃ ಪರಮ್‌ ಅವಾಪ್ಸ್ಯಥ-ಇದರಿಂದ ದೇವತೆಗಳಿಗೆ ನೆರವಾಗಿ. ಆ ದೇವತೆಗಳು\nನಿಮಗೆ ನೆರವಾಗಲಿ. ಒಬ್ಬರಿಗೊಬ್ಬರು ನೆರವಾಗುತ್ತಾ ಹಿರಿಯ ಹಿತವನ್ನು ಪಡೆಯಿರಿ.\n\nಈ ರೀತಿ ಯಜ್ಞದ ಸೃಷ್ಟಿ ಮಾಡಿದ ಚತುರ್ಮುಖ ಹೇಳಿದನಂತೆ: “ಯಜ್ಞಗಳ ಮೂಲಕ ನೀವು ದೇವತೆಗಳಿಗೆ\nನೆರವಾಗಿ ಹಾಗೂ ಅವರು ನಿಮ್ಮ ಅಭೀಷ್ಟ ವನ್ನು ಪೂರೈಸಲಿ\" ಎಂದು. \"ಹೀಗೆ ಒಬ್ಬರಿಗೊಬ್ಬರು ನೆರವಾಗುತ್ತಾ\nಹಿರಿಯ ಹಿತವನ್ನು ಪಡೆಯಿರಿ” ಎಂದನಂತೆ. ನಾವು ನಮಗೆ ಬೇಕಾದುದನ್ನು ನಾವೇ ಸೃಷ್ಟಿಸಿಕೊಳ್ಳುತ್ತೇವೆ\n\nಎನ್ನುವುದು ನಮ್ಮ ಭ್ರಮೆ. ನಾವು ಬಿತ್ತಿ ಬೆಳೆಯಬೇಕು ಎಂದರೆ ಪ್ರಕೃತಿಯಲ್ಲಿ ವಾತಾವರಣ ವೈಪರೀತ್ಯ\nಆಗಬಾರದು. ಇಲ್ಲದಿದ್ದರೆ ನಮಗೆ ಏನನ್ನೂ ಬೆಳೆಯಲು ಸಾಧ್ಯವಿಲ್ಲ. ಪ್ರತಿಯೊಂದು ಕ್ರಿಯೆಯ ಹಿಂದೆ ಅನೇಕ\nದೇವತಾಶಕ್ತಿಗಳು ಕಾರ್ಯ ನಿರ್ವಹಿಸುತ್ತಿರುತ್ತವೆ. ನಮ್ಮ ಪ್ರತಿಯೊಂದು ಅಂಗಾಂಗಳಿಗೂ ಒಬ್ಬ ಅಭಿಮಾನಿ\nದೇವತೆ ಇದ್ದಾನೆ. ಆ ಶಕ್ತಿ ಕೆಲಸ ಮಾಡದೇ ಇದ್ದರೆ ನಾವು ಏನನ್ನೂ ಮಾಡಲು ಸಾಧ್ಯವಿಲ್ಲ. ಹೀಗೆ ನಮಗೆ\nಬದುಕು ಕೊಟ್ಟು, ನೋಡುವ ಕಣ್ಣು, ಕೇಳುವ ಕಿವಿ ಕೊಟ್ಟು, ಒಳ್ಳೆಯದನ್ನು ನೋಡುವ, ಒಳ್ಳೆಯದನ್ನು ಕೇಳುವ\nಬುದ್ಧಿ ಕೊಟ್ಟು, ಈ ಎಲ್ಲಾ ಕಾರ್ಯವನ್ನು ಒಂದು ದೇವತೆಗಳ ಸಮೂಹ ನಿರಂತರ ನಡೆಸುವಂತೆ ಭಗವಂತನ\nವ್ಯವಸ್ಥೆ ಇದೆ. ಹೀಗಿರುವಾಗ ನಾವು ಇಂತಹ ದೇವತಾ ಶಕ್ತಿಗಳಿಗೆ ಕೃತಜ್ಞತೆಯನ್ನು ಸಲ್ಲಿಸಬೇಕು. ಹೀಗೆ\nಒಬ್ಬರಿಗೊಬ್ಬರು ನೆರವಾದಾಗ ನಾವು ಹಿತವನ್ನು ಕಾಣಲು ಸಾಧ್ಯ.\n\nಸಾಮಾನ್ಯವಾಗಿ ಅಗ್ನಿ ಮುಖದಲ್ಲಿ ಮಾಡುವ ಪೂಜೆಯನ್ನು ಯಜ್ಞ ಎನ್ನುವುದು ವಾಡಿಕೆ. ದೇವರ ಪೂಜೆಯಲ್ಲಿ ಅಗ್ನಿ\nಅತ್ಯಂತ ಮುಖ್ಯ ಪ್ರತೀಕ. ಏಕೆಂದರೆ ಅಗ್ನಿ ಅತ್ಯಂತ ಶುದ್ಧ. ಅಗ್ನಿಗೆ ಏನನ್ನು ಹಾಕಿದರೂ ಅದು ಶುದ್ಧವಾಗುತ್ತದೆ.\nಅಗ್ನಿ ಭಗವಂತನ ಪ್ರತೀಕ. ಭಗವಂತನಿಗೆ ಆಕಾರವಿಲ್ಲ, ಆತ ಬೆಳಕಿನ ಪುಂಜ ಹಾಗೂ ಪವಿತ್ರ. ಇದೇ ಗುಣವನ್ನು\nಅಗ್ನಿಯಲ್ಲಿ ನಾವು ಕಾಣಬಹುದು. ಇನ್ನು ನಾವು ಭಗವಂತನಿಗೆ ಏನನ್ನಾ ದರೂ ತಿನ್ನಿ ಸಬೇಕು ಎಂದರೆ ಅದು ಅಗ್ನಿ\nಮುಖೇನ ಮಾತ್ರ ಸಾಧ್ಯ. ಯಜ್ಞದಲ್ಲಿ ನಾವು ಪೂಜೆ ಮಾಡುವುದು ಬೆಂಕಿಯನ್ನಲ್ಲ, ಅಗ್ನಿ ಮುಖೇನ\nಅಗ್ನಿನಾರಾಯಣನ ಪೂಜೆ-ಯಜ್ಞ. ಈ ಅರಿವಿಲ್ಲದೆ ಯಜ್ಞವನ್ನು ಮಾಡಿದರೆ ಹೊಗೆ ತಿಂದು ಸಾಯಬೇಕಾದೀತು!\nನಮ್ಮ ಪೂಜೆ ಅಗ್ನಿ ನಾರಾಯಣನಿಂದ ಸೂರ್ಯನಾರಾಯಣನನ್ನು ಸೇರಿ, ಮರಳಿ ನರನಾರಾಯಣನನ್ನು\nತಲುಪುತ್ತದೆ. ಇದಕ್ಕಾಗಿ ದೇವರನ್ನು ಕುರಿತು ಮಾಡುವ ಯಜ್ಞ ಯಾವಾಗಲೂ ಹಗಲು ಹೊತ್ತಿನಲ್ಲೇ ನಡೆಯುತ್ತದೆ.\nಅಗ್ನಿ ಯ ಏಳು ಬಣ್ಣಗಳ ಮುಖೇನ ಸೂರ್ಯನ ಏಳು ಬಣ್ಣಗಳಲ್ಲಿ ವಿಲೀನವಾಗುವ ಯಜ್ಞಶಕ್ತಿ, ವಾತಾವರಣವನ್ನು\nಸೇರಿ ಲೋಕಕ್ಕೆ ಮಂಗಳವನ್ನುಂಟುಮಾಡುತ್ತದೆ. ಇದನ್ನು ಇಲ್ಲಿ ಕೊಡು-ಕೊಂಡುಕೊಳ್ಳುವ ಕ್ರಿಯೆ ಎಂದಿದ್ದಾರೆ.",
  "3.12": "ಇಷ್ಟಾನ್‌ ಭೋಗಾನ್‌ ಹಿ ವಃ ದೇವಾಃ ದಾಸ್ಯಂತೇ ಯಜ್ಞ ಭಾವಿತಾಃ |\nತೈಃ ದತ್ತಾನ್‌ ಅಪ್ರದಾಯ ಏಭ್ಯಃ ಯಃ ಭುಂಕ್ತೇ ಸ್ಟೇನಃ ಏವ ಸಃ -ಇಂತಹ ಯಜ್ಞದಿಂದ ಬಲಗೊಂಡ ದೇವತೆಗಳು\nನೀವು ಬಯಸಿದ ಬಯಕೆಗಳನ್ನು ಈಡೇರಿಸುತ್ತಾರೆ. ಅವರು ನೀಡಿದ್ದನ್ನು ಅವರಿಗೆ ನೀಡದೇ ತಿನ್ನು ವವನು ಕಳ್ಳನೇ\n\nಸರಿ.\n\nನಮಗೆ ಏನು ಬೇಕೋ ಅದನ್ನು ಈ ಪ್ರಕೃತಿ ಕೊಡುತ್ತದೆ. ಹಾಗಿರುವಾಗ ಅದನ್ನು ಉಪಯೋಗಿಸುವ ನಮಗೆ\nಕೃತಜ್ಞತೆ ಬೇಕು. ಅದನ್ನು ಬಿಟ್ಟು 'ಇದು ನನ್ನ ದು' ಎಂದು ಅಧಿಕಾರ ಅಹಂಕಾರ ತೋರಿದರೆ ಉದ್ಧಾರವಿಲ್ಲ. ಪ್ರಕೃತಿ\nಕೊಟ್ಟ ದ್ದನ್ನು ಕೃತಜ್ಞತೆ ಸಲ್ಲಿಸದೇ ಪಡೆದುಕೊಂಡು 'ಇದು ನನ್ನ ದು' ಎನ್ನು ವವನು ಕಳ್ಳನೇ ಸರಿ!\n",
  "3.13": "ಯಜ್ಞ ಶಿಷ್ಟ ಅಶಿನಃ ಸಂತಃ ಮುಚ್ಯಂತೇ ಸರ್ವ ಕಿಲ್ಬಿಷೈಃ |\n\nಭುಂಜತೇ ತೇ ತು ಅಘಮ್‌ ಪಾಪಾಃ ಯೇ ಪಚಂತಿ ಆತ್ಮ ಕಾರಣಾತ್‌- ದೇವತೆಗಳಿಗೆ ಸಲ್ಲಿಸಿ ಉಳಿದದ್ದನ್ನು\nಉಣ್ಣುವ ಸಜ್ಜನರು ಎಲ್ಲಾ ಪಾಪಗಳಿಂದ ಪಾರಾಗುತ್ತಾರೆ. ತಮಗಾಗಿ ಅನ್ನ ಬೇಯಿಸುವವರು ತಮ್ಮ ಪಾಪವನ್ನೇ\nತಾವು ತಿನ್ನುತ್ತಾರೆ.\n\nಯಾರು ಪಡೆದದ್ದನ್ನು ಭಗವದರ್ಪಣೆ ಮಾಡಿ ಅದನ್ನು ಭಗವಂತನ ಪ್ರಸಾದವೆಂದು ಸ್ವೀಕರಿಸುತ್ತಾರೊ, ಅವರು\nಬದುಕಿನ ಎಲ್ಲಾ ಕೊಳೆಗಳಿಂದ ಬಿಡುಗಡೆಗೊಂಡು ಸ್ವಚ್ಛ ಬದುಕಿಂದ ಬಾಳುತ್ತಾರೆ. ಯಾರ ಮನೆಯಲ್ಲಿ\nತಮಗೋಸ್ಕರ ಅನ್ನ ಬೇಯುತ್ತದೋ, ಅವನು ತಿನ್ನುವುದು ಅನ್ನವನ್ನಲ್ಲ ಪಾಪವನ್ನು. ನಮಗೆ ಈ ಆಹಾರವನ್ನು\nಕೊಟ್ಟವನು ಆ ಭಗವಂತ. ಅವನಿಗೆ ನಾವು ಮೊದಲು ಕೃತಜ್ಞತೆಯನ್ನು ತೋರಬೇಕು. ಅದನ್ನು ಬಿಟ್ಟು ಇದು ನನ್ನ\nಸಂಪಾದನೆ, ನಾನ್ಯಾಕೆ ಇದನ್ನು ಇನ್ನೊಬ್ಬರಿಗೆ ಹಂಚಬೇಕು ಎನ್ನುವ ಭಾವನೆಯನ್ನು ಬೆಳೆಸಿಕೊಂಡರೆ ನಾವು\nನಮ್ಮ ಪಾಪದ ಗಂಟನ್ನು ಬೆಳೆಸಿಕೊಳ್ಳುತ್ತೇವೆ. ಸೃಷ್ಟಿಯ ಉದ್ದೇಶದಂತೆ ನೆಡೆದುಕೊಳ್ಳದೇ ಇದ್ದರೆ\nನಾವು ಗಳಿಸಿದ್ದೂ ಸಹ ನಮಗೆ ದಕ್ಕುವುದಿಲ್ಲ.\n",
  "3.14": "ಅನ್ನಾತ್‌ ಭವಂತಿ ಭೂತಾನಿ ಪರ್ಜನ್ಯಾತ್‌ ಅನ್ನ ಸಂಭವಃ।\n\nಯಜ್ಞಾತ್‌ ಭವತಿ ಪರ್ಜನ್ಯಃ ಯಜ್ಞಃ ಕರ್ಮ ಸಮುದ್ಭವಃ -ಜೀವಿಗಳ ಹುಟ್ಟು ಆಹಾರದಿಂದ; ಆಹಾರದ ಬೆಳೆ\nಸೂರ್ಯನಿಂದ[ಮೋಡದಿಂದ]. ಸೌರಶಕ್ತಿಯ ವೃದ್ಧಿ (ಮೋಡದ ಹುಟ್ಟು]-ಯಜ್ಞದಿಂದ; ಯಜ್ಞದ ನಿರ್ವಹಣೆ-\nಕರ್ಮದಿಂದ.\n",
  "3.15": "ಕರ್ಮ ಬ್ರಹ್ಮಉದ್ಭವಮ್‌ ವಿದ್ಧಿ ಬ್ರಹ್ಮ ಅಕ್ಷರ ಸಮುದ್ಧವಮ್‌ |\nತಸ್ಮಾತ್‌ ಸರ್ವ ಗತಮ್‌ ಬ್ರಹ್ಮ ನಿತ್ಯಮ್‌ ಯಜ್ಞೇ ಪ್ರತಿಷ್ಠಿತಮ್‌ - ಕರ್ಮದ ನಿಷ್ಠತ್ತಿ ಭಗವಂತನಿಂದ;\nಭಗವಂತನ ಅಭಿವ್ಯಕ್ತಿ- ವೇದಾಕ್ಷರದಿಂದ. ಆದ್ದರಿಂದ ಎಲ್ಲೆಡೆಯಿರುವ ಭಗವಂತ ಸದಾ ಯಜ್ಞದಲ್ಲಿ ನೆಲೆಸಿದ್ದಾನೆ.",
  "3.16": "ಏವಂ ಪ್ರವರ್ತಿತಮ್‌ ಚಕ್ರಮ್‌ ನ ಅನುವರ್ತಯತಿ ಇಹ ಯಃ |\n\nಅಘ ಆಯಃ ಇಂದ್ರಿಯ ಆರಾಮಃ ಮೋಘಮ್‌ ಪಾರ್ಥ ಸಃ ಜೀವತಿ -ಹೀಗೆ ಜಗದ ಗಾಲಿಯನ್ನು\nಮುಂದುವರಿಸದವನು ಪಾಪದ ಬದುಕಲ್ಲಿ ಬದುಕುತ್ತಾ ಇಂದ್ರಿಯ ಸುಖದಲ್ಲೇ ಮೈಮರೆತವನು. ಓ ಪಾರ್ಥಾ,\nಅಂತವನ ಬದುಕು ವ್ಯರ್ಥ.\n\nಜೀವಜಾತದ ಹುಟ್ಟು ಆಹಾರದಿಂದ. ಆಹಾರವಿಲ್ಲದೇ ಬದುಕಿಲ್ಲ. ಈ ಆಹಾರ ಸಿಗುವುದು ಬೆಳೆಯಿಂದ. ಬೆಳೆಗೆ\nಮೂಲ ಸೌರಶಕ್ತಿ ಮತ್ತು ಮಳೆ. ಮಳೆ ಬರುವುದು ಯಜ್ಞದಿಂದ, ನಾವು ಮಾಡುವ ಪ್ರಾಮಾಣಿಕ ಬದುಕಿನಿಂದ,\nಭಗವದರ್ಪಣ ಬುದ್ಧಿಯಿಂದ. ಯಜ್ಞದ ನಿರ್ವಹಣೆ ಕರ್ಮದಿಂದ, ನಮ್ಮ ಕ್ರಿಯಾಶೀಲತೆಯಿಂದ. ಕರ್ಮ ಎಂದರೆ\nಕರ್ತವ್ಯಕರ್ಮ, ಪ್ರಾಮಾಣಿಕ ಕ್ರಿಯೆ. ಇಂತಹ ಕರ್ಮ ನಡೆಯುವುದು ಭಗವಂತನಿಂದ. ಈ ಭಗವಂತ(ಬ್ರಹ್ಮ)\nನೆಲೆಸಿರುವುದು ವೇದ(ಅಕ್ಷರ)ದಲ್ಲಿ. ವೇದ ಇರುವುದು ಜೀವ ಜಾತಗಳಲ್ಲಿ(ಮನುಷ್ಯನಲ್ಲಿ). ಆದ್ದರಿಂದ ಇದೊಂದು\nಚಕ್ರ. ಮಾನವ ಆಆಹಾರಣಮಳೆ ಯಜ್ಞ ಭಗವಂತ ವೇದ ಮಾನವ. ಇಲ್ಲಿ ವೇದ ಎಂದರೆ ವೇದ\nಮಂತ್ರವನ್ನು ಬಾಯಿಪಾಠ ಮಾಡುವುದಲ್ಲ. ವೈದಿಕ ವಾಜ್ಮಯದ ಎಚ್ಚರ-ಪ್ರಜ್ಞೆ. ಈ ಚಕ್ರದಲ್ಲಿ ನಾವು ನಮ್ಮ\nಕರ್ಮವನ್ನು ತೊರೆಯುವಂತಿಲ್ಲ. ಕರ್ಮವನ್ನು ಸದಾ ಯಜ್ಞವಾಗಿ, ಭಗವದರ್ಪಣವಾಗಿ ಮಾಡಬೇಕು.\nಭಗವಂತನ ಎಚ್ಚರ, ವೈದಿಕ ವಾಜ್ಮಯ ಪ್ರಜ್ಞೆ ಎಲ್ಲವೂ ಸಮನಾಗಿದ್ದರೆ ಮಳೆ, ಮಳೆಯಿಂದ ಬೆಳೆ, ಬೆಳೆಯಿಂದ\nಜೀವನ. ಈ ಚಕ್ರವನ್ನು ಯಾರು ಮುಂದುವರಿಸಿಕೊಂಡು ಹೋಗುವುದಿಲ್ಲವೋ ಅವನು ವಿಶ್ವ ಚಕ್ರದ ನಡೆಯನ್ನು\nಮುರಿದವನು, ಸಮಾಜದ ಸಹಜ ನಡೆಗೆ ಅಡ್ಡಗಾಲು ಹಾಕಿದವನು. ಅಂತವನು ಬರಿಯ ಇಂದ್ರಿಯ ಸುಖ\nಭೋಗದಲ್ಲಿ ಮೈಮರೆತು ತನ್ನ ಜೀವನವನ್ನು ವ್ಯರ್ಥ ಮಾಡಿಕೊಳ್ಳುತ್ತಾನೆ.\n\nಇಲ್ಲಿ ಹೇಳಿರುವ ಈ ವಿಶ್ವಚಕ್ರದ ಎಚ್ಚರ ನಮಗೆ ನಮ್ಮ ದೈನಂದಿನ ಕಾರ್ಯದಲ್ಲಿ ಇದ್ದರೆ ನಮ್ಮ ಜೀವನ ಸಾರ್ಥಕ.\nನಾವು ಸದಾ ಆ ವಿಶ್ವಶಕ್ತಿಯ ನಡೆಯನ್ನು ಅನುಸರಿಸಿದರೆ ನಮ್ಮ ಉದ್ಧಾರ ಸದಾಸಿದ್ಧ. ಎಂದೂ ಯಾವ\nವಿಚಾರವಾಗಿಯೂ ನಾವು ಭಯ ಪಡುವ ಅಗತ್ಯವಿಲ್ಲ. ನಮ್ಮ ದೈನಂದಿನ ಬದುಕನ್ನು ಒಂದು ಯಜ್ಞವಾಗಿ\nಮಾಡಿಕೊಂಡು, ಭಗವಂತನ ಪ್ರಜ್ಞೆಯಲ್ಲಿ ಬದುಕುವುದನ್ನು ನಾವು ರೂಢಿಸಿಕೊಳ್ಳಬೇಕು. ಇದು ನಿಜವಾದ\nಕರ್ಮಯೋಗ. ಇದುವೇ ಮೋಕ್ಷದ ನಡೆ. ಇದು ಭಗವಂತನನ್ನು ಸೇರುವ ಮಾರ್ಗ.\n\nಈ ವಿಶ್ವದಲ್ಲಿ ಎಲ್ಲವೂ ಒಂದಕ್ಕೊಂದು ಹೊಂದಿಕೊಂಡಿದೇ. ಪ್ರತಿಯೊಂದು ಪುಟ್ಟ\nಕ್ರಿಯೆಯಲ್ಲೂ ಇಡೀ ವಿಶ್ವದ ಶಕ್ತಿಗಳು ಪರೋಕ್ಷವಾಗಿ ಪಾಲ್ಗೊಳ್ಳುತ್ತವೆ. ನಾವು ಉಣ್ಣುವ ಆಹಾರದ ಹಿಂದೆ ಅನೇಕ\nಋಣಗಳಿವೆ. ಅದನ್ನು ನೆನಪಿಸದೇ ಇದ್ದರೆ ವಿಶ್ವ ಶಕ್ತಿಗೆ ಕೃತಘ್ನರಾದಂತೆ.\n\nವಿಶ್ವದ ನಡೆಯ “ಕರ್ಮಚಕ್ರ'; ಅದರಲ್ಲಿ ನಮ್ಮ 'ಕರ್ತವ್ಯಕರ್ಮ'; ನಮ್ಮ \"ಯಜ್ಞ ಯಾಗಾದಿಗಳು'-ಈ ಬಗ್ಗೆ\nವಿವರವಾಗಿ ಕೃಷ್ಣ ಹೇಳಿದ. ಆದರೆ ಇಲ್ಲಿ ನಮಗೆ ಒಂದು ಪ್ರಶ್ನೆ ಮೂಡಬಹುದು. ಅದೇನೆಂದರೆ: ಹಿಂದೆ ಕೃಷ್ಣ\n\nಜ್ಞಾನವನ್ನು ಶ್ರೇಷ್ಠ ಎಂದು ಹೇಳಿದ್ದ, ಆದರೆ ಕರ್ಮವನ್ನು ಬಿಟ್ಟಲ್ಲ ಎಂತಲೂ ಹೇಳಿದ. ಆದರೆ ಶಾಸ್ತ್ರದಲ್ಲಿ\nಜ್ಞಾನಿಗಳಿಗೆ ಕರ್ಮ ಬೇಡ ಎಂದು ಹೇಳಿದೆ. ಏನಿದರ ಅರ್ಥ? ಕೃಷ್ಣ ನಮ್ಮ ಈ ಪ್ರಶ್ನೆಯನ್ನು ಆತನೇ ಎತ್ತಿಕೊಂಡು\nಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ಉತ್ತರ ಕೊಡುತ್ತಾನೆ. ಒಬ್ಬ ಅಂತರಂಗದಲ್ಲಿ ಯಜ್ಞ ಮಾಡತಕ್ಕವನಿಗೆ ಕರ್ಮವಿದೆಯೋ?\nಅವನು ಕರ್ಮ ಮಾಡದಿದ್ದರೆ ಲೋಪವಿದೆಯೋ? ಮನುಷ್ಯ ಕರ್ಮ ಬಂಧನವಿಲ್ಲದೇ ಇರುವ ಸ್ಥಿತಿ ಯಾವುದು?\nಮೋಕ್ಷಕ್ಕೆ ಮೊದಲು ಸಂಸಾರಿಕ ಸ್ಥಿತಿಯಲ್ಲಿ ಕರ್ಮ ಮಾಡದೇ ಇರುವುದು ಸಾಧ್ಯವೋ? ಕರ್ಮವಿಲ್ಲದೆ ಸಂಪೂರ್ಣ\nಅಂತರಂಗದ ಸ್ಥಿತಿಯಲ್ಲಿರುವುದು ಸಾಧ್ಯವೋ? ಇತ್ಯಾದಿ ಪ್ರಶ್ನೆಗಳಿಗೆ ಮುಂದೆ ಕೃಷ್ಣ ವಿವರಣೆ ಕೊಟ್ಟಿದ್ದಾನೆ.\n",
  "3.17": "ಯಃ ತು ಆತ್ಮ ರತಿಃ ಏವ ಸ್ಯಾತ್‌ ಆತ್ಮ ತೃಪ್ಪಃ ಚ ಮಾನವಃ |\n\nಆತ್ಮನಿ ಏವ ಚ ಸಂತುಷ್ಟಃ ತಸ್ಯ ಕಾರ್ಯಮ್‌ ನ ವಿದ್ಯತೇ- ಪರಮಾತ್ಮನನ್ನು ಕಂಡು (ಪರಮಾತ್ಮನ\nಕರುಣೆಯಿಂದ) ಸುಖವುಂಡವನು, ಪರಮಾತ್ಮನ ಕಾಣ್ಕೆಯಿಂದ(ಕರುಣೆಯಿಂದ) ಕೃತಕೃತ್ಯನಾದವನು,\nಬೇರಾವುದೂ ಬೇಡವೆನಿಸಿ ಪರಮಾತ್ಮನಲ್ಲೇ ಆನಂದವಾಗಿರುವ ಸಮಾಧಿಮಗ್ನನು(ತೃಪ್ತನಾಗುವ ಮುಕ್ತನು)\nಮಾತ್ರವೆ ಮಾಡಬೇಕಾದ್ದೇನೂ ಇರುವುದಿಲ್ಲ.\n\nಭಗವಂತನನ್ನು ಅಂತರಂಗದಲ್ಲಿ ಕಂಡು ಪಡುವ ಆನಂದ 'ಆತ್ಮರತಿ'.. ಈ ಸ್ಥಿತಿಯನ್ನು ಸಮಾಧಿಸ್ಥಿತಿಯಲ್ಲಿ\nತಲುಪಬಹುದು. ನಿಜವಾದ ಸಮಾಧಿ ಸ್ಥಿತಿಯಲ್ಲಿ ನಮ್ಮ ಇಂದ್ರಿಯಗಳು ಮತ್ತು ಮನಸ್ಸು ಕೆಲಸ ಮಾಡುವುದಿಲ್ಲ.\nಜ್ಞಾನಸ್ವರೂಪವಾದ 'ಜೀವಸ್ವರೂಪ' ನೇರವಾಗಿ ಭಗವಂತನನ್ನು ಕಾಣುವ ಸ್ಥಿತಿ 'ಸಮಾಥಿಸ್ಥಿತಿ'. ಈ ಸ್ಥಿತಿಯಲ್ಲಿ\nಭಗವಂತನೊಡನೆ ನೇರ ಸಂಪರ್ಕ ಸಾಧ್ಯ. ಇಂತಹ ಸ್ಥಿತಿಯಲ್ಲಿರುವವನಿಗೆ ಯಾವುದೇ ಕರ್ಮದ ಲೇಪವಿಲ್ಲ.\nದೇವರನ್ನು ಕಂಡ ಮೇಲೆ ಆತನಿಗೆ ಈ ಲೌಕಿಕ ಪ್ರಪಂಚ ತೃಪ್ತಿಯಾಗಿ ಅದು ಬೇಡವೆನಿಸುತ್ತದೆ. ಕೇವಲ\nಭಗವಂತನ ಸಾಕ್ಷಾತ್ಕಾರದ ಆನಂದ ಸಾಗರದಲ್ಲಿ ಆತ ಮುಳುಗಿರುತ್ತಾನೆ. ಈ ಸ್ಥಿತಿಯಲ್ಲಿ ಆತನಿಗೆ ಯಾವುದೇ\nಕರ್ತವ್ಯ ಕರ್ಮವಿಲ್ಲ, ಆತ ವಿಧಿ ನಿಷೇಧಗಳಿಂದ ಅತೀತನಾಗಿರುತ್ತಾನೆ.\n",
  "3.18": "ನ ಏವ ತಸ್ಯ ಕೃತೇನ ಅರ್ಥಃ ನ ಅಕೃತೇನ ಇಹ ಕಶ್ಚನ |\n\nನ ಚ ಅಸ್ಯ ಸರ್ವಭೂತೇಷು ಕಶ್ಚಿತ್‌ ಅರ್ಥ ವ್ಯಪಾಶ್ರಯಃ -ಅಂತವನು ಏನನ್ನಾದರೂ ಮಾಡುವುದರಿಂದ ಹೆಚ್ಚಿನ\nಸಾಧಕವಾಗಲೀ, ಮಾಡದೇ ಇರುವುದರಿಂದ ಯಾವುದೇ ಬಾಧಕವಾಗಲೀ ಇಲ್ಲ. ಸಮಸ್ತ ಜೀವಿಗಳಲ್ಲಿ ಅವನಿಗೆ\nಯಾವುದೇ ಫಲದ ಹಂಗಿಲ್ಲ.\n\nಸಮಾಧಿ ಸ್ಥಿತಿಯಲ್ಲಿ ಅವನಿಗೆ ಹಸಿವು, ಬಾಯಾರಿಕೆ ಇಲ್ಲ. ಆತನಿಗೆ ಹೊರ ಪ್ರಪಂಚದ ಅರಿವೇ ಇರುವುದಿಲ್ಲ.\nಇಂತಹ ಸ್ಥಿತಿಯಲ್ಲಿರುವಾಗ ಇನ್ಯಾವುದೋ ಸಾಧನೆ ಮಾಡುವುದರಿಂದ ಉದ್ಧಾರವಾಗಲೀ, ಕರ್ತವ್ಯಕರ್ಮ\nಮಾಡದೇ ಇರುವ ದೋಷವಾಗಲೀ ಇರುವುದಿಲ್ಲ. ಪಂಚಭೂತಗಳ, ಪಂಚಕೋಶಗಳ ಆಸರೆ ಕೂಡಾ ಅವನಿಗೆ\nಬೇಕಾಗಿರುವುದಿಲ್ಲ. ಸಮಸ್ತ ಜನಾಂಗ, ಪರಿವಾರ ಎನ್ನುವ ಮಮಕಾರ ಈ ಸ್ಥಿತಿಯಲ್ಲಿ ಇರುವುದಿಲ್ಲ. ಆತನಿಗೆ\nಹೊರ ಪ್ರಪಂಚದ ಹಂಗಿಲ್ಲ. ಈ ರೀತಿ ಸಮಾಧಿ ಸ್ಥಿತಿಯಿಂದ ದೇವರನ್ನು ಕಾಣುತ್ತಿರುವವನು ಕರ್ತವ್ಯ ಕರ್ಮದಿಂದ\nಆಚೆಗಿರುತ್ತಾನೆ.\n",
  "3.19": "ತಸ್ಮಾತ್‌ ಅಸಕ್ತಃ ಸತತಂ ಕಾರ್ಯಮ್‌ ಕರ್ಮ ಸಮಾಚರ ।\n\nಅಸಕ್ತಃ ಹಿ ಆಚರನ್‌ ಕರ್ಮ ಪರಮ್‌ ಆಪ್ನೋತಿ ಪೂರುಷಃ -ಆದ್ದರಿಂದ ಫಲದ ನಂಟು ತೊರೆದು ಸದಾ ಕರ್ತವ್ಯ\nಕರ್ಮವನ್ನು ಮಾಡುತ್ತಿರು. ನಂಟು ತೊರೆದು ಕರ್ತವ್ಯದಲ್ಲಿ ತೊಡಗುವುದರಿಂದಲೇ ಸಾಧಕ ಭಗವಂತನನ್ನು\nಸೇರುವುದು ಸಾಧ್ಯ.\n\nಈ ಎಲ್ಲಾ ಕಾರಣದಿಂದ ನಾವು ನಮ್ಮ ಕರ್ತವ್ಯ ಕರ್ಮವನ್ನು ಮಾಡಬೇಕು. \"ಎಲ್ಲವನ್ನೂ ಮಾಡು, ಆದರೆ\nಯಾವುದನ್ನೂ ಅಂಟಿಸಿಕೊಳ್ಳದೇ ಮಾಡು. ಏನು ಮಾಡಬೇಕೋ ಅದನ್ನು ಫಲದ ಬಗ್ಗೆ ಯೋಚಿಸದೆ(ಅಧಿಕಾರ\nಸಾಧಿಸದೇ) ಮಾಡು. ಹೀಗೆ ಕರ್ಮ ಮಾಡಿದರೆ ಅದು ನಿನ್ನನ್ನು ಭಗವಂತನೆಡೆಗೆ ಕೊಂಡೊಯ್ಯುತ್ತದೆ. ಅದು\nಎಂದೂ ನಿನ್ನನ್ನು ಮತ್ತೆ ಕರ್ಮ ಬಂಧನಕ್ಕೆ ತಳ್ಳುವುದಿಲ್ಲ. ಈ ರೀತಿ ಮಾಡುವುದರಿಂದ ಭಗವಂತನನ್ನು\nಸೇರುವುದು ಸಾಧ್ಯ ಹೊರತು ಕರ್ಮ ತ್ಯಾಗದಿಂದಲ್ಲ \"ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.\n\nಇಲ್ಲಿ \"ಪೂರುಷಃ\" ಎನ್ನುವ ಪದ ಬಳಕೆಯಾಗಿದೆ. ಪುರದಲ್ಲೀಪೂರ್ಣವಾದ ಶರೀರದಲ್ಲಿ) ಇರುವವ ಪುರುಷ.\nಪುರವನ್ನು ಪೂರ್ಣ ಪ್ರಮಾಣದಲ್ಲಿ ಉಪಯೋಗಿಸುವ ಸಾಧಕ-ಪೂರುಷಃ. ಸಾಧನಾ ಶರೀರದಲ್ಲಿದ್ದು\nಸಾಧನೆಯಲ್ಲಿ ತೊಡಗಿರುವ ಜೀವ ಪೂರುಷಃ.\n\nಈ ರೀತಿ ಕರ್ಮ ಸಿದ್ಧಾಂತವನ್ನು ವಿವರಿಸಿದ ಕೃಷ್ಣ ಅದಕ್ಕೆ ಪೂರಕವಾದ ನಿದರ್ಶನವನ್ನು ಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ\nಕೊಡುತ್ತಾನೆ.",
  "3.20": "ಕರ್ಮಣಾ ಏವಹಿ ಸಂಸಿದ್ಧಿಮ್‌ ಅಸ್ಥಿತಾಃ ಜನಕ ಅದಯಃ |\nಲೋಕಸಂಗ್ರಹಮ್‌ ಏವ ಅಪಿ ಸಂಪಶ್ಯನ್‌ ಕರ್ತುಮ್‌ ಅರ್ಹಸಿ -ಕರ್ಮದಿಂದಲೇ ಸಾಧಿಸಿ ಜನಕ ಮೊದಲಾದವರು\nಗುರಿ ಮುಟ್ಟಿದರು. ಜನತೆಯನ್ನು ತಿದ್ದುವ ಹೊಣೆಯನ್ನರಿತಾದರೂ ನೀನು ಕರ್ಮ ಮಾಡಬೇಕಾಗಿದೆ.\n\nಹಿಂದಿನ ಅನೇಕ ರಾಜರ್ಷಿಗಳು ಈ ಮಾರ್ಗದಲ್ಲಿ ನಡೆದು ಮೋಕ್ಷ ಪಡೆದಿದ್ದಾರೆ. ಅವರ್ಯಾರೂ ಎಲ್ಲವನ್ನು ತ್ಯಜಿಸಿ\nಕಾಡಿಗೆ ಹೋಗಿಲ್ಲ. ಇದಕ್ಕೆ ಉತ್ತಮ ಉದಾಹರಣೆ ಜನಕ ಮಹಾರಾಜ. ಈತ ಎಲ್ಲಾ ರಾಜ್ಯ ವೈಭೋಗದೊಂದಿಗೆ\nರಾಜ್ಯಭಾರ ಮಾಡಿದ ವ್ಯಕ್ತಿ. ಆದರೆ ಅವನಷ್ಟು ದೊಡ್ಡ ಜ್ಞಾನಿ ಆ ಕಾಲದಲ್ಲಿ ಯಾರೂ ಇರಲಿಲ್ಲ. ಅಂಥಹ ಮಹಾ\nರಾಜರ್ಷಿ ಆತ. ಶುಕಾಚಾರ್ಯರು ವೈರಾಗ್ಯದ ಬಗ್ಗೆ ಸರಿಯಾದ ತಿಳುವಳಿಕೆಗಾಗಿ ಜನಕನಲ್ಲಿಗೆ ಬಂದಿದ್ದರು!\nಇದು ನಿಜವಾದ ಸಾಧಕನ ಬದುಕು. ಜನಕ ಎಲ್ಲಾ ಅಧಿಕಾರದ ಭೋಗದ ನಡುವೆ ಇದ್ದು, ವಿರಕ್ತನಾಗಿ ಬದುಕಿದವ.\nಆದ್ದರಿಂದ ಕೃಷ್ಣ ಇಲ್ಲಿ ಜನಕನ ಹೆಸರನ್ನು ಪ್ರಸ್ತಾಪಿಸುತ್ತಾನೆ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: \"ಜನಕ ಮುಂತಾದ\nರಾಜರ್ಷಿಗಳು ಕರ್ಮಯೋಗದಿಂದಲೇ ಜ್ಞಾನ ಪಡೆದು, ಕರ್ಮ ಮಾಡುತ್ತಾ ಎತ್ತರಕ್ಕೇರಿದರೇ ಹೊರತು, ಕರ್ಮ\nತ್ಯಾಗದಿಂದಲ್ಲ” ಎಂದು. ಈ ರೀತಿ ಸಮಾಜಕ್ಕೆ ಮಾರ್ಗದರ್ಶಿಯಾದ ನೀನು ಸಮಾಜಕ್ಕೋಸ್ಕರ ಯುದ್ಧ ಮಾಡು\nಎಂದು ಹೇಳುತ್ತಿದ್ದಾನೆ ಕೃಷ್ಣ\".\n\nಕರ್ತವ್ಯ ಕರ್ಮದ ಬಗ್ಗೆ ವಿವರವಾಗಿ ವಿವರಿಸಿದ ಕೃಷ್ಣ, ಈಗ ತಪ್ಪು ದಾರಿಯಲ್ಲಿ ಮುಂದಾಳು ನಡೆದಾಗ ಸಮಾಜದ\nಮೇಲಾಗುವ ಪರಿಣಾಮದ ಬಗ್ಗೆ ಸ್ವತಃ ತನ್ನನ್ನೇ ಉದಾಹರಣೆಯಾಗಿಟ್ಟುಕೊಂಡು ಮುಂದಿನ ಶ್ಲೋಕಗಳಲ್ಲಿ\nವಿವರಿಸುತ್ತಾನೆ.\n",
  "3.21": "ಯತ್‌ ಯತ್‌ ಆಚರತಿ ಶ್ರೇಷ್ಠಃ ತತ್‌ ತತ್‌ ಏವ ಇತರಃ ಜನಃ |\n\nಸಃ ಯತ್‌ ಪ್ರಮಾಣಮ್‌ ಕುರುತೇ ಲೋಕಃ ತತ್‌ ಅನುವರ್ತತೇ--ಮುಂದಾಳು ಏನೇನು ಮಾಡುತ್ತಾನೋ\nಉಳಿದ ಮಂದಿ ಅದೇ ದಾರಿ ಹಿಡಿಯುತ್ತಾರೆ. ಅವನು ಯಾವುದನ್ನು ಆಧಾರವಾಗಿ ಬಳಸುತ್ತಾನೋ ಜನತೆ\nಅದನ್ನೇ ಬೆನ್ನು ಹತ್ತುತ್ತದೆ.\n\nಸಮಾಜದಲ್ಲಿ ಹಿರಿಯನೆನಿಸಿದವ(ಶ್ರೇಷ್ಠು, ವಯಸ್ಸಿನಲ್ಲಿ, ಆಚರಣೆಯಲ್ಲಿ, ಜ್ಞಾನದಲ್ಲಿ ಸಮಾಜಕ್ಕೆ ಮಾರ್ಗದರ್ಶನ\nಮಾಡಬಲ್ಲ, ಎತ್ತರದಲ್ಲಿರುವ ವ್ಯಕ್ತಿ ಯಾವ ದಾರಿಯಲ್ಲಿ ಸಾಗುತ್ತಾನೋ, ಉಳಿದವರೂ ಅದೇ ಹಾದಿಯಲ್ಲಿ\nಸಾಗುತ್ತಾರೆ. ಇಲ್ಲಿ ಅರ್ಜುನ ಸಮಾಜದ ಮುಖಂಡ. ಆತ ಏನು ಮಾಡುತ್ತಾನೋ ಅದನ್ನೇ ಸಮಾಜ\nಹಿಂಬಾಲಿಸುತ್ತದೆ. ಏಕೆಂದರೆ ಸಾಮಾನ್ಯ ಜನರಿಗೆ ಶಾಸ್ತ್ರ ಇತ್ಯಾದಿ ತಿಳಿಯುವುದಿಲ್ಲ. ಅವರು ಕೇವಲ ಆದರ್ಶ\nವ್ಯಕ್ತಿಗಳೆನಿಸಿದವರನ್ನು ಹಿಂಬಾಲಿಸುತ್ತಾರೆ. ನಾಯಕನಾದವನು ಯಾವುದನ್ನು ಪ್ರಮಾಣವಾಗಿರಿಸಿಕೊಂಡು\nಮಾಡುತ್ತಾನೋ ಅದನ್ನೇ ಸಾಮಾನ್ಯ ಜನರು ಅನುಸರಿಸುತ್ತಾರೆ.\n\nಈ ಶ್ಲೋಕದಲ್ಲಿ ಕೃಷ್ಣ ಕೊಟ್ಟಿರುವ ಸಂದೇಶವನ್ನು ನಾವು ನಮ್ಮ ದೈನಂದಿನ ಬದುಕಿನಲ್ಲಿ ಕಾಣುತ್ತೇವೆ. ಒಂದು\nಸಂಸ್ಥೆಯನ್ನು ನಡೆಸುವ ಮುಖ್ಯಸ್ತನ ನಡವಳಿಕೆ, ಆಚರಣೆ ಸರಿದಾರಿಯಲ್ಲಿ ಇಲ್ಲದಿದ್ದರೆ, ಆ ಸಂಸ್ಥೆ\nಅಧೋಗತಿಯನ್ನು ಕಾಣುತ್ತದೆ. ದುಷ್ಟ ಶಕ್ತಿಗಳು ಎದ್ದು ನಿಲ್ಲುತ್ತವೆ. ಏಕೆಂದರೆ ಮುಖಂಡ ಎನಿಸಿದವ ಏನನ್ನು\nಅನುಸರಿಸುತ್ತಾನೋ ಅದನ್ನೇ ಪ್ರಮಾಣವಾಗಿ ಆತನ ಕೆಳಗಿರುವ ಜನರು ತಮಗರಿವಿಲ್ಲದಂತೆ\nಅನುಸರಿಸಲಾರಂಭಿಸುತ್ತಾರೆ. ಈ ಕಾರಣದಿಂದ ಒಬ್ಬ ಮುಖಂಡ ಎಷ್ಟು ಎಚ್ಚರದಿಂದಿದ್ದರೂ ಸಾಲದು. ಒಂದು\nದೇಶವನ್ನು ನಡೆಸುವ ಮುಖ್ಯಸ್ಥ ಬ್ರಷ್ಟಾಚಾರಿಯಾಗಿದ್ದಲ್ಲಿ ಇಡೀ ದೇಶ ಬ್ರಷ್ಟಾಚಾರದ ಹಾದಿಯನ್ನು ತುಳಿಯುವ\nಸಾಧ್ಯತೆ ಇದೆ. ಸಾಮಾನ್ಯವಾಗಿ ಮಾನವರು ಒಳ್ಳೆಯದನ್ನು ಅನುಸರಿಸುವುದಕ್ಕಿಂತ ಹೆಚ್ಚಾಗಿ ಹಾಗೂ\nವೇಗವಾಗಿ ಕೆಟ್ಟದ್ದನ್ನು ಅನುಸರಿಸುವುದು ಹೆಚ್ಚು. ಉದಾಹರಣೆಗೆ ಒಬ್ಬ ಉತ್ತಮ ಅಧ್ಯಾಪಕ ಧೂಮಪಾನ\nಮಾಡುವ ಹವ್ಯಾಸದವನಾಗಿದ್ದರೆ, ಆತನ ವಿದ್ಯಾರ್ಥಿಗಳು ಆತನಲ್ಲಿರುವ ಜ್ಞಾನಕ್ಕಿಂತ ಮಿಗಿಲಾಗಿ ಆತನ\nದುರಾಭ್ಯಾಸವನ್ನು ಪ್ರಮಾಣವಾಗಿರಿಸಿಕೊಂಡು ಕೆಟ್ಟ ದಾರಿ ಹಿಡಿಯುವ ಸಾಧ್ಯತೆ ಹೆಚ್ಚು. ಇದು\nಹಿರಿಯವರೆನಿಸಿದವರು ತಪ್ಪು ದಾರಿ ತುಳಿದಾಗ ಸಮಾಜದ ಮೇಲಾಗುವ ದುಷ್ಪರಿಣಾಮ. ಇದು ತುಂಬಾ\nಅಪಾಯಕಾರಿ-ಈ ಅರಿವು ನಮಗಿರಬೇಕು.",
  "3.22": "ನ ಮೇ ಪ್ರಾರ್ಥ ಅಸ್ತಿ ಕರ್ತವ್ಯಮ್‌ ತ್ರಿಷು ಲೋಕೇಷು ಕಿಂಚನ |\n\nನ ಅನವಾಪ್ತ್ರಮ್‌ ಅವಾಪ್ತವ್ಯಮ್‌ ವರ್ತೇ ಏವ ಚ ಕರ್ಮಣಿ -- ಪಾರ್ಥಾ, ಮೂರು ಲೋಕಗಳಲ್ಲೂ ನಾನು\nಮಾಡಬೇಕಾದ್ದೂ ಏನೂ ಇಲ್ಲ. ಪಡೆಯದೇ ಇದ್ದು ಪಡೆಯಬೇಕಾದದ್ದೂ ಇಲ್ಲ. ಆದರೂ ನಾನು ಕರ್ಮದಲ್ಲಿ\nತೊಡಗಿದ್ದೇನೆ.\n",
  "3.23": "ಯದಿ ಹಿ ಅಹಮ್‌ ನ ವರ್ತೇಯಮ್‌ ಜಾತು ಕರ್ಮಣಿ ಅತಂದ್ರಿತಃ\n\nಮಮ ವರ್ತ್ಮ ಅನುವವರ್ತಂತೇ ಮನುಷ್ಯಾಃ ಪಾರ್ಥ ಸರ್ವಶಃ -. ಓ ಪಾರ್ಥಾ, ನಾನು ಎಂದಾದರೂ\nಎಚ್ಚರದಿಂದ ಕರ್ಮದಲ್ಲಿ ತೊಡಗದೇ ಹೋದರೆ, ಮನುಷ್ಯರು ಎಲ್ಲಾ ಬಗೆಯಿಂದಲೂ ನನ್ನ ದಾರಿ ಹಿಡಿದು\nಬಿಡುತ್ತಾರೆ.\n",
  "3.24": "ಉತ್ಸೀದೇಯಃ ಇಮೇ ಲೋಕಾಃ ನ ಕುರ್ಯಾಮ್‌ ಕರ್ಮ ಚೇತ್‌ ಅಹಮ್‌ |\n\nಸಂಕರಸ್ಯ ಚ ಕರ್ತಾ ಸ್ಯಾಮ್‌ ಉಪಹನ್ಯಾಮ್‌ ಇಮಾಃ ಪ್ರಜಾಃ -- ನಾನು ಕರ್ಮ ಮಾಡದೇ ಇದ್ದರೆ ಈ\nಜನರೆಲ್ಲಾ ದಾರಿ ತಪ್ಪಿ ಹಾಳಾಗುತ್ತಾರೆ. ಧರ್ಮದ ಕಲಬೆರೆಕೆಗೆ ಕಾರಣನಾಗಿ ಈ ಎಲ್ಲಾ ಜನತೆಯನ್ನು ನಾನೇ\nಕೈಯಾರ ಕೆಡವಿದಂತಾದೀತು.\n\nಈ ಮೇಲಿನ ಮೂರು ಶ್ಲೋಕದಲ್ಲಿ ಕೃಷ್ಣ ತನ್ನನ್ನೇ ತಾನು ಉದಾಹರಣೆಯಾಗಿಟ್ಟುಕೊಂಡು ಹಿಂದೆ ಹೇಳಿದ\nವಿಷಯವನ್ನು ವಿವರಿಸುತ್ತಾನೆ. ಅರ್ಜುನನ ಸಾರಥಿಯಾಗಿ ನಿಂತಿರುವ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ- \"ನನಗೆ ಏನಾದರೂ\nಮಾಡಬೇಕಾದ್ದು ಅಥವಾ ಮಾಡದೇ ಇದ್ದರೆ ತೊಂದರೆ ಆಗುವಂತಾದ್ದು ಏನೂ ಇಲ್ಲ, ಆದರೆ ನಾನು ಕರ್ತವ್ಯ\nಕರ್ಮದಲ್ಲಿ ನಿಂತಿದ್ದೇನೆ” ಎಂದು. ಮೂರು ಲೋಕದಲ್ಲಿ, ಸೃಷ್ಟಿ-ಸ್ಥಿತಿ-ಸಂಹಾರವನ್ನು ತನ್ನ ನಿತ್ಯ ಕರ್ಮವಾಗಿ\nಮಾಡುತ್ತಿರುವ ಭಗವಂತ, ಎಲ್ಲವನ್ನು ತನ್ನ ಪ್ರೀತಿಯ ಭಕ್ತರಿಗಾಗಿ, ಜೀವಜಾತಕ್ಕಾಗಿ ಮಾಡುತ್ತಿದ್ದಾನೆಯೇ\nಹೊರತು ಇನ್ನೆ ೀನೋ ಲಾಭಕ್ಕಾಗಿ ಅಲ್ಲ.\n\nಒಂದು ವೇಳೆ ಕೃಷ್ಣ ತನ್ನನ್ನು ನಿತ್ಯ ಕರ್ಮದಲ್ಲಿ ತೊಡಗಿಸಿಕೊಳ್ಳದೇ ಇದ್ದಿದ್ದರೆ ಎಲ್ಲರೂ ಆತನನ್ನು\nಪ್ರಮಾಣವಾಗಿರಿಸಿಕೊಂಡು ಆತನ ದಾರಿಯನ್ನು ಹಿಡಿಯುತ್ತಿದ್ದರು. ಈ ಕಾರಣಕ್ಕಾಗಿ ಭಗವಂತ ಅವತಾರ\nತಾಳಿದಾಗ ಒಬ್ಬ ಸಾಮಾನ್ಯ ಮಾನವನಂತೆ ಕಾಣಿಸಿಕೊಂಡು, ತನ್ನ ನಿತ್ಯ ಕರ್ಮಗಳನ್ನು, ಕರ್ತವ್ಯ ಕರ್ಮವನ್ನು\nನಿರ್ವಹಿಸುತ್ತಾನೆ. ಕೃಷ್ಣಾವತಾರದಲ್ಲಿ ನೋಡಿದರೆ ಕೃಷ್ಣ ಸಂಧ್ಯಾವಂದನೆ ಇತ್ಯಾದಿ ಮೂಲ ಕರ್ಮವನ್ನು ತಪ್ಪದೇ\nಮಾಡುತ್ತಿದ್ದ. ಇದು ಆತನಿಗೋಸ್ಕರವಲ್ಲ, ಆತನನ್ನು ಹಿಂಬಾಲಿಸುವ ಜನರಿಗೆ ಮಾರ್ಗದರ್ಶನಕ್ಕೋಸ್ಕರ.\n\nಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ \"ನಾನು ಕರ್ಮ ಮಾಡದೇ ಇದ್ದರೆ ಇಡೀ ಲೋಕ ಕರ್ಮ ಪ್ರಜ್ಞೆಯನ್ನು ಕಳೆದುಕೊಂಡು\nದಾರಿತಪ್ಪಿಬಿಡುತ್ತದೆ, ಸ್ವಚ್ಛಂದತೆ ಬಂದು ನಿರ್ದಿಷ್ಟ ವ್ಯವಸ್ಥೆ ಹೊರಟು ಹೋಗುತ್ತದೆ\" ಎಂದು. ಯಾರಿಗೆ ಯಾವುದು\nಧರ್ಮವೋ ಅದನ್ನು ಮಾಡಲೇ ಬೇಕು. ಅದೊಂದು ವ್ಯವಸ್ಥೆ. ಇಲ್ಲದಿದ್ದರೆ ಎಲ್ಲರೂ ತಮಗೆ ತೋಚಿದಂತೆ\nಮಾಡಲಾರಂಭಿಸಿಬಿಡುತ್ತಾರೆ. \"ಇದರಿಂದ ಅವ್ಯವಸ್ಥೆ ತಾಂಡವವಾಡುತ್ತದೆ ಹಾಗೂ ಅದಕ್ಕೆ ಜವಾಬ್ದಾರಿ\nನಾವಾಗುತ್ತೇವೆ” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.",
  "3.25": "ಸಕ್ತಾಃ ಕರ್ಮಣಿ ಅವಿದ್ವಾಂಸಃ ಯಥಾ ಕುರ್ವಂತಿ ಭಾರತ |\n\nಕುರ್ಯಾತ್‌ ವಿದ್ವಾನ್‌ ತಥಾ ಅಸಕ್ತಃ ಚಿಕೀರ್ಷುಃ ಲೋಕ ಸಂಗ್ರಹಮ್‌ -- ಓ ಭಾರತಾ, ತಿಳಿಯದ ಮಂದಿ ಫಲದ\nನಂಟಿಗಾಗಿ ಕರ್ಮಗಳನ್ನು ಮಾಡುತ್ತಾರೆ ಹೇಗೋ, ಹಾಗೇ ತಿಳಿದವನೂ ಕರ್ಮ ಮಾಡುತ್ತಿರಬೇಕು-ಫಲದ ನಂಟು\nತೊರೆದು, ಸಮಾಜವನ್ನು ತಿದ್ದುವುದಕ್ಕಾಗಿ.\n\nತಿಳುವಳಿಕೆ ಇಲ್ಲದವರು ಫಲಾಪೇಕ್ಷೆಯಿಂದ ಕರ್ಮ ಮಾಡುತ್ತಾರೆ. ಆದರೆ ತಿಳಿದವನು, ಜ್ಞಾನಿ, ಯಾವುದೇ ಫಲದ\nಅಧಿಕಾರ ಸಾಧಿಸದೇ, ನಿಷ್ಕಾಮ ಕರ್ಮ ಮಾಡುತ್ತಿರಬೇಕು. \"ನಾನು ನನ್ನ ಕಣ್ಮುಂದೆ ಬೆಳೆಯುತ್ತಿರುವ\nಜನಾಂಗಕ್ಕೆ ಮಾರ್ಗದರ್ಶಕನಾಗಿ ಭಗವಂತನ ಸೇವೆ ಮಾಡುತ್ತಿದ್ದೇನೆ, ನನಗೆ ಇದರಿಂದ ಭಗವಂತ ಏನು\nಕೊಟ್ಟರೂ ಸಂತೋಷ\" ಎಂಬ ಸಂಕಲ್ಪದಿಂದ ಕರ್ಮ ಮಾಡಬೇಕು. ಇದು ನಿಜವಾದ ಕರ್ಮಯೋಗ.",
  "3.26": "ನ ಬುದ್ಧಿ ಭೇದಮ್‌ ಜನಯೇತ್‌ ಅಜ್ಞಾನಾಮ್‌ ಕರ್ಮ ಸಂಗಿನಾಮ್‌ |\n\nಜೋಷಯೇತ್‌ ಸರ್ವ ಕರ್ಮಾಣಿ ವಿದ್ವಾನ್‌ ಯುಕ್ತಃ ಸಮಾಚರನ್‌--ತಿಳುವಳಿಕೆಯಿಲ್ಲದೆ ಫಲದ ನಂಟಿಗಾಗಿಯೇ\nಕರ್ಮ ಮಾಡುವ ಮಂದಿಯ ನಂಬಿಕೆಯನ್ನು ನಲುಗಿಸಬಾರದು. ಉಪಾಯ ಬಲ್ಲ ತಿಳಿದವನು ತಾನು ಎಲ್ಲಾ\nಕರ್ಮಗಳನ್ನು ಮಾಡುತ್ತಾ ಅವರನ್ನು ಒಲೈಸಬೇಕು.\n\nಸಮಾಜದಲ್ಲಿ ಅನೇಕ ತರದ ಜನರಿರುತ್ತಾರೆ. ಎಲ್ಲರಿಗೂ ತಿಳುವಳಿಕೆ ಇರುವುದಿಲ್ಲ. ಅವರು ಅವರ ನಂಬಿಕೆಗೆ\nತಕ್ಕಂತೆ ನೆಡೆದುಕೊಳ್ಳುತ್ತಿರುತ್ತಾರೆ. ತಿಳಿದವನಿಗೆ ಅದು ಮೂಢನಂಬಿಕೆಯಾಗಿ ಕಾಣಬಹುದು. ಆದರೆ ಎಂದೂ\nಒಮ್ಮೆಗೇ ಹೋಗಿ ಅಂತಹ ಜನರನ್ನು ಪರಿಹಾಸ್ಯ ಮಾಡಬಾರದು. ಒಬ್ಬ ಒಂದು ಕಲ್ಲನ್ನು ಅದಕ್ಕೊಂದು ಹೆಸರನ್ನು\nಕೊಟ್ಟು ದೇವರೆಂದು ಪೂಜಿಸುತ್ತಿರಬಹುದು. ಆತನ ಅಪಾರ ನಂಬಿಕೆ ಶರಣಾಗತಿ ಆತನನ್ನು ರಕ್ಷಿಸುತ್ತಿರುತ್ತದೆ.\nಇದನ್ನು ನೋಡಿ ಪರಿಹಾಸ್ಯ ಮಾಡುವುದು ಮೂಢತನ. ಅವರು ಇಂತಹ ನಂಬಿಕೆಯ ನೆಲಗಟ್ಟಿನಲ್ಲಿ ಜೀವನದಲ್ಲಿ\nಭರವಸೆಯಿಂದ ಬದುಕುತ್ತಿರುತ್ತಾರೆ.ಅವರಿಗೊಂದು ಸನಾತನ ಪ್ರಜ್ಞೆ ಇರುತ್ತದೆ. ಸರ್ವಗತ, ಸರ್ವಶಬ್ದವಾಚ್ಯ\nಹಾಗೂ ಸರ್ವಶಕ್ತ ಭಗವಂತ ಆತನಿಗೆ ಕಲ್ಲಿನ ಮುಖೇನ ರಕ್ಷಣೆ ಕೊಡಲೂ ಸಾಧ್ಯವಿದೆಯಲ್ಲವೇ? ಆದ್ದರಿಂದ\nಎಂದೂ ಅಂತವರನ್ನು ನೋಡಿ ನಗಬಾರದು. ಅದನ್ನು ಬಿಟ್ಟು ಅವನನ್ನು ಕ್ರಮೇಣವಾಗಿ ಜ್ಞಾನದ ಪರಿದಿಗೆ ತರುವ\nಪ್ರಯತ್ನವನ್ನು ಮಾಡಬೇಕು. ಎಲ್ಲವನ್ನು ಸಾಮಾಜಿಕ ಕಾಳಜಿಯಿಂದ ಮಾಡಬೇಕು, ಆದರೆ ನಿರ್ಲಿಪ್ತನಾಗಿ ಎಲ್ಲಾ\nಕರ್ಮವನ್ನು ಮಾಡುತ್ತಾ ಅಜ್ಞಾನಿಗಳಲ್ಲಿ ಜ್ಞಾನವನ್ನು ತುಂಬಬೇಕು.",
  "3.27": "ಪ್ರಕೃತೇಃ ಕ್ರಿಯಮಾಣಾನಿ ಗುಣೈಃ ಕರ್ಮಾಣಿ ಸರ್ವಶಃ |\n\nಅಹಂಕಾರವಿಮೂಢ ಆತ್ಮಾ ಕರ್ತಾ ಅಹಮ್‌ ಇತಿ ಮನ್ಯತೇ--ಪ್ರಕೃತಿಯ ಅಂಗಾಂಗಗಳಾದ\nಇಂದ್ರಿಯಾದಿಗಳಿಂದ(ಭಗವದಧೀನವಾದ, ಜೀವನ ಸ್ವಭಾವ ಸಹಜವಾದ ಗುಣಗಳಿಂದ) ಎಲ್ಲಾ ಬಗೆಯ\nಕರ್ಮಗಳೂ ನಡೆಯುತ್ತಿರುತ್ತವೆ. ಹಮ್ಮಿನಿಂದ ಮೈಮರೆತವನು 'ನಾನೇ ಮಾಡಿದೆ' ಎಂದು ತಿಳಿಯುತ್ತಾನೆ.\n\nಈ ಶ್ಲೋಕ ಅನೇಕ ವಿಧದಲ್ಲಿ ತೆರೆದುಕೊಳ್ಳುತ್ತದೆ. ಇಲ್ಲಿ ಕೃಷ್ಣ ಮುಖ್ಯವಾಗಿ 'ನಾನೇ ಮಾಡಿದೆ' ಎಂದು ಅಹಂಕಾರ\nಪಡುವುದು ಎಷ್ಟು ತಪ್ಪು ಮತ್ತು ಏಕೆ ಎನ್ನುವುದನ್ನು ವಿವರಿಸಿದ್ದಾನೆ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ \"ಯಾರಾದರೂ\nಏನನ್ನಾದರೂ 'ನಾನೇ ಮಾಡಿದೆ' ಎಂದು ತಿಳಿದುಕೊಂಡರೆ ಅದು ಅವನ ತಿಳಿಗೇಡಿತನ\" ಎಂದು. ಸೃಷ್ಟಿಯಲ್ಲಿನ\nಒಂದು ವಿಚಿತ್ರವೆಂದರೆ ಯಾರೂ ಏನನ್ನೂ ಮಾಡುವುದಿಲ್ಲ-ಆದರೆ ಎಲ್ಲವೂ ಎಲ್ಲರ ಕೈಯಿಂದ ಆಗುತ್ತಿರುತ್ತದೆ! ಈ\nದೇಹ (ಪಿಂಡಾಂಡ) ಪ್ರಕೃತಿಯ ನಿರ್ಮಾಣ. ಪ್ರಕೃತಿಯಲ್ಲಿ ಅದಕ್ಕೆ ಪೋಷಕವಾದ ಅಂಗಭೂತವಾದ\nಇಂದ್ರಿಯಗಳಿವೆ. ಪ್ರಕೃತಿ ಎಂದರೆ ಈ ದೇಹ, ಅದರ ಗುಣಗಳು ಎಂದರೆ ಇಂದ್ರಿಯಗಳು. ಶಬ್ದ-ಸ್ಪರ್ಶ-ರಸ-ರೂಪ-\nಗಂಧ; ಕಿವಿ-ತೊಗಲು-ನಾಲಿಗೆ-ಕಣ್ಣು-ಮೂಗು; ಅದಕ್ಕೆ ಅನುಗುಣವಾಗಿ ಆಕಾಶ(ಶಬ್ದ), ಗಾಳಿ(ಸ್ಪರ್ಶ),\nನೀರು(ರಸ), ಅಗ್ನಿ (ರೂಪ), ಮತ್ತು ಮಣ್ಣು(ಗಂಧ) ಇವು ಪ್ರಕೃತಿಯ ಗುಣಗಳು. ಹೀಗಿರುವಾಗ ನಾವು\nಯಾವುದೋ ಒಂದು ವಿಷಯವನ್ನು ನಾನೇ ಮಾಡಿದೆ ಎಂದು ಹೇಳುವುದು ಅರ್ಥ ಶೂನ್ಯ. ಉದಾಹರಣೆಗೆ\n'ಕಣ್ಣಿನಿಂದ ನೋಡಿದೆ; ಈ ಕಣ್ಣನ್ನು ನಮಗೆ ಕೊಟ್ಟವನು ಯಾರು? ಹುಟ್ಟು ಕುರುಡನಿಗೆ ಕಣ್ಣು ಕೊಡಲು ನಿನಗೆ\nಸಾಧ್ಯವೇ? ಅಂದರೆ ಕಣ್ಣು ಪ್ರಕೃತಿಯ ಕೊಡುಗೆ. ಭಗವಂತ ನಮಗೆ ಕಣ್ಣು ಕೊಟ್ಟ, ಕಣ್ಣ ಮುಂದೆ ನೋಡುವ\nವಸ್ತುವನ್ನಿಟ್ಟ, ನೋಡುವಂತೆ ಪ್ರೇರೇಪಿಸಿದ- ನಾವು ನೋಡಿದೆವು! ಒಂದು ವೇಳೆ ನಮಗೆ ಒಳ್ಳೆಯ ಸ್ವರವಿದ್ದರೆ\nಅದಕ್ಕಾಗಿ ಅಹಂಕಾರ ಪಡುತ್ತೇವೆ. ಆದರೆ ಈ ಸ್ವರವನ್ನು ನಮಗೆ ಕೊಟ್ಟವನು ಯಾರು? ಈ ಬಗ್ಗೆ ಎಂದೂ ನಾವು\nಯೋಚಿಸುವುದಿಲ್ಲ. ಒಂದು ಕಾರ್ಯವಾಗಬೇಕಾದರೆ ಇಡೀ ವಿಶ್ವದ ಅನೇಕ ಘಟಕಗಳು ಸೇರಿ ಕಾರ್ಯ\nನಿರ್ವಹಿಸಬೇಕು. ಪ್ರಕೃತಿ ಜಡ ಅದಕ್ಕೆ ಇಚ್ಛೆ ಇಲ್ಲ. 'ನಾವು ಮಾಡುವುದು' ಅಂದರೆ ಇಚ್ಛಿಸಿ ಮಾಡುವುದು. ನಮಗೆ\nಇಚ್ಛೆ ಇದೆ; ಪ್ರತಿಯೊಬ್ಬ ಜೀವನಿಗೂ ಅವನದೇ ಆದ ಜೀವ ಸ್ವಭಾವವಿದೆ. ನಾವು ಮಾಡುವ ಪ್ರತಿಯೊಂದು\nಕಾರ್ಯ ನಮ್ಮ ಜೀವ ಸ್ವಭಾವಕ್ಕೆ ಅನುಗುಣವಾಗಿರುತ್ತದೆ. ಇದು ಇಚ್ಛಾ ಪೂರ್ವಕ ಕ್ರಿಯೆ. ನಮಗೆ ಇಚ್ಛೆ ಇದೆ\nಆದರೆ ಇಚ್ಛಾ ಸ್ವಾತಂತ್ರ್ಯವಿಲ್ಲ.\n\nಇಚ್ಛಾಸ್ವಾತಂತ್ರ್ಯ ಇರುವುದು ಕೇವಲ ಭಗವಂತನಲ್ಲಿ. ಅದಕ್ಕನುಗುಣವಾಗಿ ಸರ್ವಕಾರ್ಯ ನಿರ್ವಹಣೆ ಆಗುತ್ತದೆ.\nಆದ್ದರಿಂದ ನಮ್ಮ ಸ್ವಭಾವವನ್ನು ನಿಯಂತ್ರಿಸುವವ ಇಡೀ ಜಗತ್ತಿನ ಮೂಲ ಕರ್ತೃ ಭಗವಂತ. ಅವನ\nಇಚ್ಛೆಗನುಗುಣವಾಗಿ ಪ್ರಪಂಚದ ವ್ಯಾಪಾರ ನಡೆಯುತ್ತದೆ. ಇದು ವಿಶ್ವದ ವ್ಯವಸ್ಥೆ. ಇಡೀ ವಿಶ್ವದ ಕರ್ಮ ಚಕ್ರದಲ್ಲಿ\nನಾವು ಒಂದು ಘಟಕ ಅಷ್ಟೆ ಆದ್ದರಿಂದ 'ನಾನೇ ಮಾಡಿದೆ' ಎಂದು ಅಹಂಕಾರ ಪಡುವುದರಲ್ಲಿ ಯಾವ ಅರ್ಥವೂ\nಇಲ್ಲ. ನಿಜವಾದ ಕರ್ತೃ ಭಗವಂತ. ಜೀವನಿಗೊಂದು ಕರ್ತೃತ್ವ ಹಾಗೂ ಜಡಕ್ಕೊಂದು ಕರ್ತ್ಯೃತ್ವವಿದೆ. ಇದರ\nಅಂತರ ನಮಗೆ ತಿಳಿದಿರಬೇಕು. ಮಣ್ಣು ಜಡ ಅದಕ್ಕೆ ಇಚ್ಛೆ ಇಲ್ಲ. ಬೀಜ ಚೇತನ, ಅದಕ್ಕೆ ಮರವಾಗುವ\nಸ್ವಭಾವವಿದೆ ಆದರೆ ಸ್ವಾತಂತ್ರ್ಯವಿಲ್ಲ. ಬೀಜವನ್ನು ಬಿತ್ತಿ ಬೆಳೆಸುವ ತೋಟಗಾರ ಆ ಭಗವಂತ. ಭಗವಂತನ\nಇಚ್ಛೆಗನುಗುಣುವಾಗಿ, “ಜೀವ' ನಲ್ಲಿರುವ ಸ್ವಭಾವಕ್ಕನುಗುಣವಾಗಿ ಪ್ರಪಂಚದಲ್ಲಿ ಕ್ರಿಯೆ ನಡೆಯುತ್ತದೆ. ಒಂದು\nಕ್ರಿಯೆಯ ಹಿಂದೆ ಇಡೀ ವಿಶ್ವದ ಪಾಲುದಾರಿಕೆ ಇರುತ್ತದೆ.\n",
  "3.28": "ತತ್ತ್ವವಿತ್‌ ತು ಮಹಾಬಾಹೋ ಗುಣ ಕರ್ಮ ವಿಭಾಗಯೋಃ |\n\nಗುಣಾಃ ಗುಣೇಷು ವರ್ತಂತೇ ಇತಿ ಮತ್ವಾ ನ ಸಜ್ಜತೇ- ಓ ಮಹಾವೀರಾ, ಇಂದ್ರಿಯಾದಿಗಳ(ಜೀವ ಸ್ವಭಾವದ\nಗುಣಗಳ) ಮತ್ತು ಕ್ರಿಯೆಗಳ ಪ್ರಭೇದಗಳ ನಿಜವನ್ನರಿತವನು, ಇಂದ್ರಿಯಗಳ ವಿಷಯಗಳಲ್ಲಿ ಚರಿಸುತ್ತವೆ\nಎಂದರಿತು ಅವುಗಳನ್ನು ಅಂಟಿಸಿಕೊಳ್ಳುವುದಿಲ್ಲ.\n\nತತ್ವವನ್ನು ಅರಿತ ಅಥವಾ ಯಥಾರ್ಥವನ್ನು ಅರಿತ ತತ್ವವಾದಿ-ಗುಣಕರ್ಮ, ಇಂದ್ರಿಯ ಮತ್ತು ಅದರಲ್ಲಿನ\nಕ್ರಿಯಾಭೇದವನ್ನು ತಿಳಿದಿರಬೇಕು. ಮೂಲಭೂತವಾಗಿ ಇಂದ್ರಿಯಗಳಲ್ಲಿ ಸಾತ್ವಿಕ, ರಾಜಸ ಮತ್ತು ತಾಮಸವೆಂಬ\nತ್ರೈಗುಣ್ಯಗಳಿಂದ ಕರ್ಮ ನಡೆಯುತ್ತಿರುತ್ತದೆ. ಇದು. ನಾವು ಹಿಂದೆ ಅಂಟಿಸಿಕೊಂಡು ಬಂದುದರ\nಪ್ರಭಾವವಿರಬಹುದು. ಇದರಿಂದ ಆಗುವ ಕರ್ಮವನ್ನು ನಾವು ತಟಸ್ಥರಾಗಿ ನೋಡುತ್ತಿರಬೇಕು. ಈ ವಿಷಯ\nಮನೋಶಾಸ್ತ್ರಕ್ಕೆ ಸಂಬಂಧಪಟ್ಟದ್ದು. ನಾವೇ ಮಾಡುವ ಕ್ರಿಯೆಯನ್ನು ನಾವೇ ತಟಸ್ಥರಾಗಿ ವಿಶ್ಲೇಷಿಸುವುದು!\nನನ್ನ ಮೇಲೆ ತ್ರೈಗುಣ್ಯದ ಯಾವ ಗುಣ ಪ್ರಭಾವಬೀರುತ್ತಿದೆ ಎನ್ನುವುದನ್ನು ಸ್ವಯಂ ವಿಶ್ಲೇಷಣೆ(Self Analysis)\nಮಾಡಿ, ಗುಣಕರ್ಮ ವಿಭಾಗ ತತ್ವವನ್ನು ತಿಳಿದುಕೊಂಡಾಗ, ತ್ರೈಗುಣ್ಯದ ಪ್ರಭಾವದ ಅರಿವಾಗುತ್ತದೆ. ಆಗ\nನಮಗೆ ಅದರಲ್ಲಿ ಒಡೆತನವಿಲ್ಲ ಎನ್ನುವ ಸತ್ಯ ತಿಳಿಯುತ್ತದೆ.ಇಂದ್ರಿಯಗಳು- ಅದರ ಮೇಲೆ ಪ್ರಕೃತಿಯ ತೈೈಗುಣ್ಯ-\nಅದರ ಮೇಲೆ ಜೀವ ಸ್ವಭಾವ-ಅದರ ಮೇಲೆ ಭಗವಂತನ ಜ್ಞಾನಾನಂದ- ಇವೆಲ್ಲವೂ ಕರ್ಮವಾಗಿ ಇಂದ್ರಿಯದ\nಮೂಲಕ ಅಭಿವ್ಯಕ್ತವಾಗುತ್ತಿರುತ್ತದೆ. ಜಡದಲ್ಲಿ ಬರಿಯ ಕೃತಿ(Action), ಜೀವನಲ್ಲಿ ಇಚ್ಛೆ ಮತ್ತು ಕೃತಿ (Intentional Action) ಹಾಗೂ ಭಗವಂತನಲ್ಲಿ ಸ್ವತಂತ್ರ ಇಚ್ಛಾಕೃತಿ(Independent Intentional Action)-ಇದು ಕರ್ಮಭೇದ.\nಹೀಗೆ ಗುಣಭೇದ ಮತ್ತು ಕರ್ಮಭೇದವನ್ನು ಅರಿತವನು 'ತತ್ತ್ವವಿತ್‌'. ಈ ತತ್ವ ಅರ್ಥವಾದರೆ \"ನಾನು ಮಾಡಿದೆ\"\nಎನ್ನುವ ಅಹಂಕಾರ ಎಂದೂ ನಮ್ಮನ್ನು ಕಾಡುವುದಿಲ್ಲ.\n\nಈ ಮೇಲಿನ ವಿಷಯವನ್ನು ಉದಾಹರಣೆಯೊಂದಿಗೆ ನೋಡುವುದಾದರೆ-ಸ್ವಾರಸ್ಯವಾಗಿ, ವಿಷಯಗರ್ಭಿತವಾಗಿ\nಮಾತನಾಡುವ ಒಬ್ಬ ಮಾತುಗಾರನನ್ನು ನೋಡಿ: ಆತ ಹೀಗೆ ಮಾತನಾಡಬೇಕಾದರೆ ಕೇವಲ ಬಾಯಿ ಇದ್ದರೆ\nಸಾಲದು, ಬಾಯಿಯಲ್ಲಿ ಶಬ್ದ ಬರಬೇಕು. ಕೇವಲ ಶಬ್ದವಲ್ಲ-ಯಾವ ಮಾತನಾಡಬೇಕೋ ಅದಕ್ಕನುಗುಣವಾದ\nಶಬ್ದ ಬರಬೇಕು. ಆ ಶಬ್ದ ಬರಬೇಕಾದರೆ ಮಾತಿಗೆ ಒಂದು ಭಾವ ಬೇಕು. ಭಾವ ಅನ್ನುವುದು ಮನಸ್ಸಿ ನಲ್ಲಿ\nಹೊಳೆಯಬೇಕು. ಹೊಳೆದ ಭಾವಕ್ಕೆ ತಕ್ಕಂತೆ ಶಬ್ದ ಬರಬೇಕು. ಆ ಶಬ್ದ ಬಾಯಿಯಲ್ಲಿ ಸ್ಟುಟವಾಗಿ ಹೊರ\nಹೊಮ[ ಬೇಕು. ಭಾವನೆಯಿಂದ ಶಬ್ದ ಹುಟ್ಟ ಬೇಕಾದರೆ ಮಾಧ್ಯಮವಾಗಿ ಆಕಾಶ ಮತ್ತು ಗಾಳಿ ಅಗತ್ಯ. ಈ ಎಲ್ಲಾ\nಕ್ರಿಯೆ ಸುಸೂತ್ರವಾಗಿ ನಡೆದರೆ ಮಾತ್ರ ಆತ ಚೆನ್ನಾಗಿ ಮಾತನಾಡಬಲ್ಲ. ಮನಸ್ಸಿನಲ್ಲಿ ಭಾವ ಮತ್ತು ಶಬ್ದವನ್ನು\nಹೊಳೆಸುವವನು ಯಾರು? ಒಂದು ವೇಳೆ ಹೇಳಬೇಕು ಅನ್ನುವ ವಿಷಯಕ್ಕೆ ಅನುಗುಣವಾದ ಶಬ್ದ ಹೊಳೆಯದೇ\nಇದ್ದರೆ? ನಮ್ಮ ಮೆದುಳಿನಲ್ಲಿ ಯಾವುದೋ ಒಂದು ಗುಂಡಿ ಆ ಕ್ಷಣದಲ್ಲಿ ಕೆಲಸ ಮಾಡದೇ ಇದ್ದರೆ? ಇಲ್ಲಿ ನಮ್ಮ\nಕೈವಾಡ ಏನಿದೆ? ಇದು ತಿಳಿದಾಗ ಅಹಂಕಾರ ಬಾರದು. ಈ ಅರಿವಿದ್ದಾಗ ಎಲ್ಲರೊಡನೆ ಎಲ್ಲರಂತೆ ಇದ್ದು\nಅಂಟಿಸಿಕೊಳ್ಳದೇ ಇರಲು ಸಾಧ್ಯ.\n\nಇಂದ್ರಿಯಗಳಲ್ಲಿ ಸತ್ವ-ರಜೋ-ತಮೋ ಗುಣಗಳು ಜೀವ ಸ್ವಭಾವಕ್ಕನುಗುಣವಾಗಿ ಕೆಲಸ ಮಾಡುತ್ತವೆ.\nಭಗವಂತನ ಜ್ಞಾನಾನಂದ ಸ್ವರೂಪ- ಜೀವನ ಜ್ಞಾನೇಂದ್ರಿಯ ಗುಣಗಳನ್ನು ನಿಯಂತ್ರಿಸುತ್ತವೆ. ಇದನ್ನು ತಿಳಿದಾಗ\n\nನಾನು-ನನ್ನದು ಎನ್ನುವುದು ಹೊರಟು ಹೋಗುತ್ತದೆ. ವಿಶ್ವವೆಂಬ ಈ ಮಹಾ ಸಾಗರದಲ್ಲಿ ನಾನೊಂದು ಮರಳಿನ\nಕಣ ಎನ್ನುವ ನಿಜ ತಿಳಿಯುತ್ತದೆ. ವಿಶ್ವದ ವಿಶ್ವತೋಮುಖವಾದ ಅಸ್ತಿತ್ವ ಗುರುತಿಸಿದವ \"ನಾನು ಮಾಡಿದೆ”\nಎಂದು ಎಂದೂ ಹೇಳುವುದಿಲ್ಲ ಹಾಗೂ ಯಾವುದನ್ನೂ ಅಂಟಿಸಿಕೊಳ್ಳ(Attachment)ವುದಿಲ್ಲ.\n\nಈ ಶ್ಲೋಕದಲ್ಲಿ ಕೃಷ್ಣ ಅರ್ಜುನನನ್ನು 'ಮಹಾಬಾಹೋ' ಎಂದು ಸಂಬೋಧಿಸಿದ್ದಾನೆ. ಮೇಲ್ನೋಟದಲ್ಲಿ\nಮಹಾಬಾಹು ಎಂದರೆ ವೀರ, ಹೋರಾಟಗಾರ. ಬಲಿಷ್ಠ ತೊಳಿನವನಾದ ನೀನು ಹೇಡಿಯಾಗದೇ ಹೋರಾಡು\nಎನ್ನುವುದು ಇಲ್ಲಿ ಕಾಣುವ ಭಾವ. ಆದರೆ ಅದರಿಂದಾಚೆಗೆ ಇನ್ನೂ ಅನೇಕ ಅರ್ಥವಿದೆ. \"ಮಹತ್‌ ವಹತೀತಿ\nಮಹಾಬಾಹು'. ಅಂದರೆ ದೊಡ್ಡದ್ದನ್ನು ಹೊತ್ತುಕೊಂಡವ. ಜಗತ್ತಿನ ಮೂಲಭೂತವಾದ ಸತ್ಯವನ್ನು ಹೃದಯದಲ್ಲಿ\nಹೊತ್ತವ ಎಂದರ್ಥ. “ಜಗತ್ತಿನ ಮಹತ್ತಾದ ಸಂಗತಿಯನ್ನು ಗ್ರಹಿಸಬಲ್ಲ ಅರಿವಿನ ಮಹಾತೋಳಿನಿಂದ\nದಿಗಂತದಾಚೆಗಿನ ಸತ್ಯ(ಭಗವಂತ)ವನ್ನು ಹಿಡಿ” ಎನ್ನುವುದು ಈ ಸಂಬೋಧನೆಯ ಹಿಂದಿರುವ ಇನ್ನೊಂದು\n\nಭಾವ.",
  "3.29": "( ಣ್ಗ ೦\n\nಪ್ರಕೃತೇಃ ಗುಣ ಸಮ್ಮೂಢಾಃ ಸಜ್ಜಂತೇ ಗುಣಕರ್ಮಸು |\n\nತಾನ್‌ ಅಕೃತ್ಸ್ನವಿದಃ ಮಂದಾನ್‌ ಕೃತ್ಸ್ನವಿತ್‌ ನ. ವಿಚಾಲಯೇತ್‌ -- ಪ್ರಕೃತಿಯ ಅಂಗಾಂಗಗಳಾದ\nಇಂದ್ರಿಯಾದಿಗಳಲ್ಲೇ ಮೈಮರೆತವರು ಇಂದ್ರಿಯಾದಿಗಳ ಕ್ರಿಯೆಯಲ್ಲೇ ಅಂಟಿಕೊಳ್ಳುತ್ತಾರೆ. ಪೂರ್ತಿ\nನಿಜವನ್ನರಿಯದ ಅಂತಹ ಮಂದಿಯನ್ನು ಪೂರ್ತಿ ಅರಿತವರು ಗೊಂದಲಗೆಡಿಸಬಾರದು.\n\nಪ್ರಕೃತಿಯ ಗುಣಭೂತವಾಗಿರುವ ಇಂದ್ರಿಯ ಸುಖದಲ್ಲಿ ಮುಳುಗಿದವರು; ಮೂಲ ಪ್ರಕೃತಿಯ ತ್ರಿಗುಣದ\nಮೋಹಕ್ಕೊಳಗಾಗಿ, ಸತ್ಯವನ್ನರಿಯದೇ, ಮೋಹದಲ್ಲಿರುವವರು; ತಾನು ಭಗವಂತನ ಗುಣದ ಅಧೀನ ಎನ್ನುವ\nಎಚ್ಚರ ಇಲ್ಲದೇ ಇರುವವರು- ಇವರನ್ನು ಕೃಷ್ಣ 'ಪ್ರಕೃತೇರ್ಗುಣ ಸಮ್ಮೂಡಢಾಃ' ಎಂದು ಕರೆದಿದ್ದಾನೆ. ಇಂಥವರು\nಭಗವಂತನ ಗುಣ ಕರ್ಮವನ್ನು ತಮ್ಮದೇ ಎಂದು ಭ್ರಮಿಸಿಕೊಂಡು, 'ನಾನೇ ಎಲ್ಲಾ ನನ್ನಿಂದಲೇ ಎಲ್ಲಾ' ಎಂದು\nಬದುಕುತ್ತಿರುತ್ತಾರೆ. ಇಂತವರಿಗೆ ಸತ್ಯವನ್ನು ಅಥವಾ ಪೂರ್ಣವನ್ನು ಅರಿಯುವ ಯೋಗ್ಯತೆ ಇರುವುದಿಲ್ಲ.\nಅಂತವರನ್ನು 'ಪೂರ್ಣವನ್ನು ಅರಿತವರು' ಗೊಂದಲಗೆಡಿಸಲು ಹೋಗಬಾರದು. ಅವರಲ್ಲಿ ಸತ್ಯವನ್ನು ತಿಳಿಯುವ\nಯೋಗ್ಯತೆ ಇದ್ದರೆ ಅವರು ಆ ಸ್ಥಿತಿಯಿಂದಾಚೆಗೆ ಬರುತ್ತಾರೆ. ಇಲ್ಲದ ಯೋಗ್ಯತೆಯನ್ನು ಯಾರೂ ಅವರಲ್ಲಿ\nತುಂಬಿಸಲಾರರು; ಇದ್ದ ಯೋಗ್ಯತೆಯನ್ನು ಯಾರೊಬ್ಬರೂ ಕಸಿಯಲಾರರು. ಯಾರಿಗೆ ಸತ್ಯವನ್ನು ತಿಳಿಯುವ\nಅಪೇಕ್ಷೆ ಇದೆಯೋ ಅವರೊಂದಿಗೆ ಸೇರಿ ಅವರ ಸಹವಾಸ ಮಾಡಿ ಅವರಿಂದ ಕಲಿಯಬಹುದು ಅಥವಾ ಅವರಿಗೆ\nತಿಳಿಹೇಳಬಹುದು.",
  "3.30": "ಮಯಿ ಸರ್ವಾಣಿ ಕರ್ಮಾಣಿ ಸಂನ್ಯಸ್ಯ ಅಧ್ಯಾತ್ಮ ಚೇತಸಾ ।\nನಿರಾಶೀಃ ನಿರ್ಮಮಃ ಭೂತ್ವಾ ಯುಧ್ಯಸ್ವ ವಿಗತ ಜ್ವರಃ-ಎಲ್ಲಾ ಕರ್ಮಗಳನ್ನು ನನ್ನಲ್ಲಿ ಅರ್ಪಿಸಿ, ನನ್ನಲ್ಲೇ\nಮನವಿಟ್ಟು, ಹಂಬಲ ತೊರೆದು, ಮಮಕಾರ ತೊರೆದು,ಚಳಿ ಬಿಟ್ಟು ಹೋರಾಡು.\n\nಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ \"ನೀನು ಮಾಡುವ ಸರ್ವಕರ್ಮವನ್ನು ನನಗರ್ಪಿಸಿ ಕರ್ಮ ಮಾಡು\" ಎಂದು. ಇಲ್ಲಿ 'ಸಂನ್ಯಸ್ಯ'\nಎನ್ನುವ ಪದ ಬಳಕೆಯಾಗಿದೆ. ನಾನು ಮಾಡಿದ್ದೆಲ್ಲವೂ ನಾನೇ ಮಾಡಿದ್ದಲ್ಲ. ಏನು ಕ್ರಿಯೆ ನನ್ನಿಂದಾಯಿತೋ ಅದು\nನನ್ನ ಕೈಯಿಂದ ಭಗವಂತ ಮಾಡಿಸಿದ್ದು. ಏನು ನನ್ನ ಮೂಲಕ ನಡೆಯಿತೋ ಅದು ಭಗವಂತನ ಪೂಜೆ ಎನ್ನುವ\nಸಮರ್ಪಣಾ ಭಾವ ಸಂನ್ಯಾಸ. \"ನಾಹಂ ಕರ್ತಾ ಹರಿ ಕರ್ತಾ; ಹರಿ ಕರ್ತಾ ಹಿ ಕೇವಲಮ್‌”\" ; \"ನನ್ನ\nಬಾಯಿಯಿಂದ ಏನು ಬಂತೋ ಅದು ನಿನ್ನ ಸ್ತೋತ್ರವಾಗಲಿ. ನನ್ನ ಮನಸ್ಸಿನ ಮೂಲಕ ನಡೆಯುವುದೆಲ್ಲವೂ ನಿನ್ನ\nಸ್ಮರಣೆಯಾಗಲಿ. ಎಲ್ಲವೂ ನಿನ್ನ ಪೂಜೆಯಾಗಲಿ ಅನ್ನುವ ಚಿಂತನೆ ಬೆಳೆಸಿಕೊ-ಯುದ್ಧ ಮಾಡುವಾಗಲೂ ಸಹ\"\n\nಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.\n\nಇಲ್ಲಿ ಯುದ್ಧ ಸಮಷ್ಟಿಯಾಗಿ ತೀರ್ಮಾನವಾಗಿರುವುದು. ಸುಮಾರು ಹದಿಮೂರು ವರ್ಷಗಳ ಹಿಂದೆ ಧರ್ಮರಾಯ\nರಾಜಸೂಯ ಯಾಗ ಮಾಡಿದಾಗ ಅಲ್ಲಿ ಶಿಶುಪಾಲನ ತಲೆ ಉರುಳುತ್ತದೆ. ಆಗ ಧರ್ಮರಾಯನಿಗೆ ವ್ಯಾಸರು\n\"ಇದು ಮುಂದೆ ಸುಮಾರು ಹದಿಮೂರು ವರ್ಷಗಳ ನಂತರ ನಡೆಯುವ ಮಹಾ ಯುದ್ಧದ ಮುನ್ಸೂಚನೆ” ಎಂದು\nಹೇಳುತ್ತಾರೆ. ಅಂದರೆ ಈ ಯುದ್ಧ ವಿಧಿಲಿಖಿತ. ಇಲ್ಲಿ ಅರ್ಜುನ ಕೇವಲ ಉಪಕರಣ(Instrument) ಅಷ್ಟೇ.\nಆದ್ದರಿಂದ “ಭಗವಂತನಲ್ಲಿ ಮನವನ್ನಿಟ್ಟು ಹಂಬಲ-ಮಮಕಾರ ತೊರೆದು ನಿಶ್ಚಿಂತೆಯಿಂದ ಹೋರಾಡು” ಎಂದು\nಕೃಷ್ಣ ಅರ್ಜುನನಿಗೆ ಹೇಳುತ್ತಾನೆ.\n\nನಮ್ಮ ಬದುಕೇ ಒಂದು ಹೋರಾಟ. ಈ ಹೋರಾಟದಲ್ಲಿ ನಾವು ಮಾಡುವ ಕಾರ್ಯವನ್ನು ನಾವು\nಪ್ರಾಮಾಣಿಕವಾಗಿ ಮಾಡಬೇಕು. ಏನು ಆಗಬೇಕೋ ಅದು ಆಗಿಯೇ ತೀರುತ್ತದೆ. ಅದನ್ನು ತಡೆಯಲು ನಮ್ಮಿಂದ\nಸಾಧ್ಯವಿಲ್ಲ. ಭಗವಂತ ನನಗೆ ವಹಿಸಿದ ಕೆಲಸವನ್ನು ಆತನೇ ನನ್ನ ಕೈಯಿಂದ ಮಾಡಿಸಿದ, ಇದು\nಅವನಿಗರ್ಪಿತವಾಗಲಿ, ಅವನ ಪೂಜೆಯಾಗಲಿ. ಏನು ಫಲ ಬಂತೋ ಅದು ಭಗವಂತನ ಪ್ರಸಾದ. ಈ\nಸಂಕಲ್ಪವನ್ನಿಟ್ಟು ಕಾರ್ಯ ನಿರ್ವಹಿಸಿದಾಗ ಏನೇ ಆದರೂ ಅದರ ಹೊಣೆಯನ್ನು ಭಗವಂತ ಹೊರುತ್ತಾನೆ.\nಇದಕ್ಕಿಂತ ದೊಡ್ಡ ಪೂಜೆ ಯಾವುದೂ ಇಲ್ಲ. ಇದು ಗೀತೆ ಮೂಲಕ ಕೃಷ್ಣ ನಮಗೆ ಕೊಟ್ಟ ಜೀವನ ಸಂದೇಶ. ಇದರ\nಫಲಶ್ರುತಿ ಎಂಬಂತೆ ಮುಂದಿನ ಎರಡು ಶ್ಲೋಕಗಳಿವೆ.",
  "3.31": "ಯೇ ಮೇ ಮತಮ್‌ ಇದಮ್‌ ನಿತ್ಯಮ್‌ ಅನುತಿಷ್ಠಂತಿ ಮಾನವಾಃ ।\nಶ್ರದ್ಧಾವಂತಃ ಅನಸೂಯಂತಃ ಮುಚ್ಯಂತೇ ತೇ ಅಪಿ ಕರ್ಮಭಿಃ -ಯಾವ ಮನುಷ್ಯರು ಕಿಚ್ಚು ಪಡದೇ ನನ್ನ ಈ\nಸಿದ್ಧಾಂತವನ್ನು ನಂಬಿ ನಡೆಯುವರೋ ಅವರು ಕರ್ಮಗಳಿಂದ ಪಾರಾಗುತ್ತಾರೆ.\n\n\"ಎಲ್ಲವನ್ನೂ ಭಗವಂತ ನನ್ನ ಕೈಯಿಂದ ಮಾಡಿಸುತ್ತಿದ್ದಾನೆ, ನಾನು ಮಾಡುವುದೆಲ್ಲವೂ ಅವನ ಪೂಜೆ, ನನಗೆ\nಯಾವ ಫಲದಿಂದ ಒಳಿತು ಎನ್ನುವುದು ನನಗಿಂತ ಭಗವಂತನಿಗೆ ಚೆನ್ನಾಗಿ ತಿಳಿದಿದೆ. ಆದ್ದರಿಂದ ಫಲದಲ್ಲಿ\nಅಧಿಕಾರ ಬಯಸದೇ ಬಂದಿದ್ದನ್ನು ಭಗವಂತನ ಪ್ರಸಾದ ಎಂದು ಸ್ವೀಕರಿಸಿ ಬದುಕುವುದು\". ಇದು ನಮ್ಮ\nಜೀವನದ ನಿತ್ಯಾನುಷ್ಠಾನದ ಪರಿಯಾಗಬೇಕು. ಜೀವನದ ಪ್ರತೀ ಕ್ಷಣದಲ್ಲೂ ಈ ಅನುಸಂಧಾನವಿರುವ\nಮಾನವರು(Human being, ಜ್ಞಾನಿಗಳು, ಮನುಷ್ಯತ್ವ ಉಳ್ಳವರು) ಅಶ್ರದ್ಧೆ(ರಾಜಸ) ಹಾಗೂ\nಅಸೂಯೆ(ತಾಮಸ) ತೊರೆದು ನಿಷ್ಕಾಮಕರ್ಮ ಮಾಡಿದಾಗ, ಅವರ ಜ್ಞಾನ ವೃದ್ಧಿಯಾಗುತ್ತದೆ. ಅದರಿಂದ\nಅವರು ಕರ್ಮ ಬಂಧನವನ್ನು ಕಳಚಿಕೊಂಡು ಮೋಕ್ಷಕ್ಕೆ ಹೋಗಲು ಅರ್ಹರಾಗುತ್ತಾರೆ. ನಿತ್ಯಾನುಷ್ಠಾನದಲ್ಲಿ ಈ\nಅನುಸಂಧಾನವಿದ್ದಾಗ ನಮ್ಮ ಕರ್ಮವೇ ನಮ್ಮನ್ನು ಕರ್ಮ ಬಂಧನದಿಂದ ಕಳಚುವುದಕ್ಕೆ ಮೆಟ್ಟಿಲಾಗುತ್ತದೆ\nಹಾಗೂ ಕರ್ಮ ಬಂಧನದಿಂದ ಪಾರು ಮಾಡುತ್ತದೆ.\n\nಯೇ ತ್ವೇತದಭ್ಯಸೂಯಂತೋ ನಾನುತಿಷ್ಠಂತಿ ಮೇ ಮತಮ್‌।\nಸರ್ವಜ್ಞಾನವಿಮೂಢಾಂಸ್ತಾನ್‌ ವಿದ್ಧಿನಷ್ಟಾ ನಚೇತಸಃ ॥೩೦೨॥\n\nಯೇ ತು ಏತತ್‌ ಅಭ್ಯಸೂಯಂತಃ ನ ಅನುತಿಷ್ಠಂತಿ ಮೇ ಮತಮ್‌ |\n\nಸರ್ವ ಜ್ಞಾನ ವಿಮೂಢಾನ್‌ ತಾನ್‌ ವಿದ್ಧಿ ನಷ್ಟಾನ್‌ ಅಚೇತಸಃ -ಯಾರು ಕಿಚ್ಚಿನಿಂದ ನನ್ನ ಸಿದ್ದಾಂತವನ್ನು\nಆಚರಣೆಗೆ ತರುವುದಿಲ್ಲವೋ ಅವರು ಎಲ್ಲಾ ತಿಳಿವಿಗೂ ಎರವಾದವರು. ವಿನಾಶದತ್ತ ಸರಿವ ತಿಳಿಗೇಡಿಗಳು-\nಎಂದು ತಿಳಿ.\n\nಮೇಲೆ ಹೇಳಿದ ಅನುಷ್ಠಾನವನ್ನು ಅರಿಯದೇ, ಅಸೂಯೆ-ಅಸಹನೆಯಿಂದ, 'ನನ್ನ ಕೆಲಸಕ್ಕೆ ನಾನೊಬ್ಬನೇ\nಜವಾಬ್ದಾರ, ನಾನು ಮಾಡುವುದು ನನ್ನ ಸ್ವಂತ ಹಿತಾಸಕ್ತಿಗಾಗಿ, ಅದರ ಫಲವನ್ನು ನಾನು ಪಡೆಯುತ್ತೇನೆ, ನನ್ನ\nಕೈಯಲ್ಲಿ ನನ್ನ ಅಸ್ತಿತ್ವವಿದೆ, ಯಾವ ದೇವರೂ ಅದಕ್ಕೆ ಹೊಹೆಗಾರನಲ್ಲ' ಎಂದು ಅಭಿಪ್ರಾಯ ತೋರಿ\nಅಹಂಕಾರದಿಂದ ಬದುಕುವವರಿಗೆ ಎಂದೂ ಅರಿವಿನ ಬಾಗಿಲು ತೆರೆಯುವುದಿಲ್ಲ. ಆತ ಪ್ರಪಂಚದಲ್ಲಿ\nವಿಮೂಢ(ಶ್ರೇಷ್ಠ ದಡ್ಡ)ಎನಿಸುತ್ತಾನೆ. ಆತನಿಗೆ 'ತನಗೆ ಏನೂ ಗೊತ್ತಿಲ್ಲ ಎನ್ನುವ ವಿಷಯವೂ ಗೊತ್ತಿರುವುದಿಲ್ಲ!'\nಇಂತವರಿಗೆ ಸತ್ಯದ ಬಗ್ಗೆ ಚಿಂತನೆ ಮಾಡುವ ಅರ್ಹತೆ ಇರುವುದಿಲ್ಲ. ಅಂತವರು ವಿನಾಶದತ್ತ ನಡೆಯುವ\nತಿಳಿಗೇಡಿಗಳು. ಅವರು ಕತ್ತಲಿನಿಂದ ಕತ್ತಲಿಗೆ ಹೋಗುತ್ತಾ ಅಧಃಪಾತವನ್ನು ತಲುಪಿ ತನ್ನ ಅಸ್ತಿತ್ವವನ್ನು\nಕಳೆದುಕೊಳ್ಳುತ್ತಾರೆ.\n\nಕೃಷ್ಣನ ಈ ಮೇಲಿನ ಸಂದೇಶವನ್ನು ಕೇಳಿದಾಗ ನಮಗೊಂದು ಪ್ರಶ್ನೆ ಬರುತ್ತದೆ. ಜಗತ್ತಿನ ಮೂಲಭೂತವಾದ ಈ\nಸತ್ಯವನ್ನು ಏಕೆ ಎಲ್ಲರೂ ಅನುಸರಿಸುವುದಿಲ್ಲ? ಎಂದು. ಇದಕ್ಕೆ ತುಂಬಾ ರೋಚಕವಾದ ಉತ್ತರವನ್ನು ಕೃಷ್ಣ\nಮುಂದಿನ ಎರಡು ಶ್ಲೋಕಗಳಲ್ಲಿ ಕೊಡುತ್ತಾನೆ.",
  "3.32": "ಸದೃಶಮ್‌ ಚೇಷ್ಟತೇ ಸ್ವಸ್ಯಾಃ ಪ್ರಕೃತೇಃ ಜ್ಞಾನವಾನ್‌ ಅಪಿ |\n\nಪ್ರಕೃತಿಮ್‌ ಯಾಂತಿ ಭೂತಾನಿ ನಿಗ್ರಹಃ ಕಿಮ್‌ ಕರಿಷ್ಯತಿ -- ಎಷ್ಟು ತಿಳಿದವನಾದರೂ ತನ್ನ ಸಂಸ್ಕಾರಕ್ಕೆ\n(ಸ್ವಭಾವಕ್ಕೆ) ತಕ್ಕಂತೆಯೇ ನಡೆದುಕೊಳ್ಳುತ್ತಾನೆ. ಎಲ್ಲಾ ಜೀವಿಗಳೂ ಸಂಸ್ಕಾರದ(ಸ್ವಭಾವದ) ಕೈಗೊಂಬೆಗಳು.\nಅದುಮಿಟ್ಟರೇನು ಬಂತು?\n\nಯಾರು ಎಷ್ಟೇ ಉಪದೇಶ ಮಾಡಿದರೂ ಇಡೀ ಜಗತ್ತಿನಲ್ಲಿ ಎಲ್ಲರೂ ಒಂದೇ ಮಾರ್ಗ ಅನುಸರಿಸುವುದು ಎಂದೂ\nಸಾಧ್ಯವಿಲ್ಲ. ಇದಕ್ಕೆ ಕಾರಣ ನಮ್ಮ ನಡೆ, ನಮ್ಮ ಸಂಸ್ಕಾರ, ಹಾಗೂ ನಮ್ಮ ಜೀವ ಸ್ವಭಾವ. ನಾವು ನಮ್ಮ\nಪೂರ್ವ ಸಂಸ್ಕಾರವನ್ನು ನೋಡಿದರೆ-ಸಾತ್ವಿಕ, ರಾಜಸ, ತಾಮಸವಾದ ಅನೇಕ ಅನುಭವಗಳು ಜನ್ಮ-\nಜನ್ಮಾಂತರಗಳಿಂದ ಸುಪ್ರ್ಪಪ್ರಜ್ಞೆಯಲ್ಲಿರುತ್ತವೆ. ಅನೇಕ ಜನ್ಮಗಳ ಮೂಲಕ ಹರಿದು ಬಂದ ಈ ಜೀವಕ್ಕೆ ಅನೇಕ\nಜನ್ಮಗಳ ಅನುಭವದ ಸಂಸ್ಕಾರವಿದೆ. ಒಂದೇ ಜನ್ಮವನ್ನು ನೋಡಿದರೂ ಕೂಡಾ, ಬೆಳೆದು ಬಂದ\nವಾತಾವರಣದ ಛಾಪು, ಈ ಪ್ರಭಾವ, ಸದಾ ನಮ್ಮ ಮೇಲಿರುತ್ತದೆ. ಇದಲ್ಲದೆ ಪ್ರತೀ ವ್ಯಕ್ತಿಗೆ ಆತನದೇ ಆದ\nಜೀವಸ್ವಭಾವವಿರುತ್ತದೆ. ಆತ ಸದಾ ಅದಕ್ಕೆ ತಕ್ಕಂತೆ ನಡೆದುಕೊಳ್ಳುತ್ತಾನೆ. ಮೆಣಸಿನ ಗಿಡ ಹೇಗೆ ಸಿಹಿಯಾದ\nಹಣ್ಣನ್ನು ನೀಡಲಾರದೋ ಹಾಗೇ ಒಬ್ಬ ವ್ಯಕ್ತಿಯ ಜೀವಸ್ವಭಾವವನ್ನು ಬದಲಿಸುವುದು ಅಸಾಧ್ಯ. ಸ್ವಭಾವ ಮತ್ತು\nಪ್ರಭಾವದ ಸಮ್ಮಿಶ್ರಣ ಈ ಬದುಕು.\n\nಈ ಮೇಲಿನ ವಿಶ್ಲೇಷಣೆಯನ್ನು ನೋಡಿದಾಗ ಸಹಜವಾಗಿ ನಮಗೊಂದು ಪ್ರಶ್ನೆ ಮೂಡುತ್ತದೆ. “ಜೀವ\nಸ್ವಭಾವದಂತೆ ಜೀವದ ನಡೆ; ಸ್ವಭಾವದಂತೆ ಕ್ರಿಯೆ; ಸ್ವಭಾವಕ್ಕೆ ತಕ್ಕಂತೆ ಎಲ್ಲವೂ ಆಗುತ್ತದೆ. ಹಾಗಾದರೆ\nಪ್ರಯತ್ನ ಏಕೆ ಮಾಡಬೇಕು?” ಎಂದು. ಏಕೆಂದರೆ ಸದಾ ಪ್ರಯತ್ನ ಮಾಡುವುದರಿಂದ ಸಂಸ್ಕಾರದಿಂದ ಅಥವಾ\nಪ್ರಭಾವದಿಂದ ಈಚೆ ಬರಲು ಸಾಧ್ಯ. ಸಹಜ ಸ್ವಭಾವದಲ್ಲಿ ನಿಲ್ಲುವ ತನಕ ಪ್ರಭಾವದಿಂದ ಪಾರಾಗುವ ನಿರಂತರ\nಪ್ರಯತ್ನ ಅಗತ್ಯ. ನಿರಂತರ ಅಧ್ಯಾತ್ಮ ಸಾಧನೆ ನಮ್ಮ ಸಹಜ ಸ್ವಭಾವವನ್ನು ಅಭಿವ್ಯಕ್ತಗೊಳಿಸಲು ಸಹಾಯ\nಮಾಡುತ್ತದೆ.",
  "3.33": "ಇಂದ್ರಿಯಸ್ಯ ಇಂದ್ರಿಯಸ್ಯ ಅರ್ಥೇ ರಾಗ ದ್ವೇಷೌ ವ್ಯವಸ್ಥಿತೌ ।\nತಯೋಃ ನ ವಶಮ್‌ ಆಗಚ್ಛೇತ್‌ ತೌ ಹಿ ಅಸ್ಯ ಪರಿಪಂಥಿನೌ -- ಪ್ರತಿಯೊಂದು ಇಂದ್ರಿಯ ಮತ್ತು ಅದರ ವಿಷಯದಲ್ಲಿ ರಾಗ-ದ್ವೇಷಗಳು ನೆಲೆಸಿವೆ. ಅವುಗಳ ವಶಕ್ಕೆ ಬೀಳಬಾರದು; ಅವೇ ಸಾಧಕನ ದಾರಿಯ ಶತ್ರುಗಳು.",
  "3.34": "ಇಂದ್ರಿಯಸ್ಯ ಇಂದ್ರಿಯಸ್ಯಅರ್ಥೇ ರಾಗ ದ್ವೇಷೌ ವ್ಯವಸ್ಥಿತ |\nತಯೋಃ ನ ವಶಮ್‌ ಅಗಚ್ಛೇತ್‌ ತೌ ಹಿ ಅಸ್ಯ ಪರಿಪಂಥಿನೌ--ಒಂದೊಂದು ಇಂದ್ರಿಯದ ವಿಷಯದಲ್ಲೂ ಒಲವು -\nಹಗೆತನಗಳು ತುಂಬಿವೆ. ಅವುಗಳಿಗೆ ಬಲಿಯಾಗಬಾರದು. ಅವೇ ಸಾಧಕನ ಹಗೆಗಳು.\n\nನಮ್ಮ ಇಂದ್ರಿಯಗಳಲ್ಲಿ ಎರಡು ವಿಷಯಗಳು ನಮ್ಮ ಶತ್ರುಗಳಾಗಿ ಕೆಲಸ ಮಾಡುತ್ತವೆ. ಅವುಗಳೆಂದರೆ\nರಾಗ(ಇಷ್ಟ ಪಡುವುದು, Attachment; ಹಾಗೂ ಬೇಕು ಎನ್ನು ವ ಬಯಕೆಕಾಮ, Desire). ಇಷ್ಟಪಡುವುದು-\nರಾಗ, ಅದರಿಂದ ಕಾಮ. ಇಷ್ಟ ಆಗದೇ- ದ್ವೇಷ, ಅದರಿಂದ ಕೋಪ. ಒಂದು ವಸ್ತುವನ್ನು ಬಯಸಿದೆವು, ಅದು\nಸಿಗಲಿಲ್ಲ ಆಗ ಸಿಟ್ಟು. ಅದು ಇನ್ನೊಬ್ಬರಿಗೆ ಸಿಕ್ಕಿತು ಆಗ ದ್ವೇಷ, ಸಿಕ್ಕಿತು ಆದರೆ ಅದು ನಾವು ಅಂದುಕೊಂಡಂತೆ\nಇಲ್ಲ ಆಗ ಕೋಪ. ಮೂಲಭೂತವಾಗಿ ಇರತಕ್ಕ ದೊಡ್ಡ ದೋಷ ಬಯಕೆ. ಯಾವುದನ್ನು ಹೆಚ್ಚು ಹೆಚ್ಚು\nಬಯಸುತ್ತೇವೋ ಅದರಿಂದ ಹೆಚ್ಚು ಹೆಚ್ಚು ದುಃಖಕ್ಕೀಡಾಗುತ್ತೇವೆ. ಬಯಕೆಯನ್ನು ಸೀಮಿತಗೊಳಿಸದೇ ಮೇಲೆ\nಬರಲು ಸಾಧ್ಯವಿಲ್ಲ. ನಮ್ಮ ಪ್ರತಿಯೊಂದು ಇಂದ್ರಿಯದಲ್ಲಿ ರಾಗ-ದ್ವೇಷ; ಕಾಮ-ಕ್ರೋಧ ತುಂಬಿರುತ್ತದೆ. ಆದರೆ\nನಾವು ಎಂದೂ ಈ ಬೇಕು ಬೇಡಗಳಿಗೆ, ರಾಗ ದ್ವೇಷಗಳಿಗೆ ವಶವಾಗಬಾರದು. ನನ್ನದು ಎನ್ನುವ ಅತಿ ಅನುರಾಗ\n(Possessiveness) ನಮ್ಮನ್ನು ಅಧಃಪತನಕ್ಕೆ ಕೊಂಡೊಯ್ಯುತ್ತದೆ. ನನಗೆ ಬೇಕು, ಅದು ಇನ್ನೊಬ್ಬರಿಗೆ\nಸಿಗಬಾರದು ಎನ್ನುವುದು ಪ್ರತೀ ಇಂದ್ರಿಯದಲ್ಲಿ ತುಂಬಿದೆ. ಇದು. ನಮ್ಮ ಪ್ರವೃತ್ತಿಯ ಹಿಂದಿರುವ\nಅಹಂಕಾರ(Ego). ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: \"ಎಂದೂ ಈ ಬೇಕು ಬೇಡಗಳ ದಾಸನಾಗಬೇಡ, ಅವು ನಿನ್ನ ಸಾಧನೆಯ\nದಾರಿಗೆ ಅಡ್ಡಗೋಡೆ. ಅವು ನಿನ್ನ ನಿಜ ಶತ್ರುಗಳು\" ಎಂದು.\n\nನಾವು. ಈ ಶತ್ರುಗಳಿಗೆ ಬಲಿಯಾಗದೇ, ನಮ್ಮ ಇಂದ್ರಿಯಗಳನ್ನು ನಾವೇ ವಿಶ್ಲೇಷಿಸಬೇಕು. ನನ್ನ ಇಂದ್ರಿಯ\nಏನನ್ನು ಬಯಸುತ್ತಿದೆ, ಏಕೆ ಬಯಸುತ್ತಿದೆ, ಅದರ ಹಿಂದಿರುವ ಸ್ವಾರ್ಥ-ದ್ವೇಷವೇನು, ಇದು ನನ್ನನ್ನು\nದಾರಿತಪ್ಪಿಸುವ ಬಯಕೆಯೋ ಅಥವಾ ಮೇಲಕ್ಕೆ ತರುವ ಬಯಕೆಯೋ? ಹೀಗೆ ವಿಚಾರ ಮಾಡಿ ನಮ್ಮ\nಬಯಕೆಗಳ ಶುದ್ಧೀಕರಣ ಮಾಡಿಕೊಳ್ಳಬೇಕು. ವೇದದಲ್ಲಿ ಹೇಳುವಂತೆ 'ಹಿಟ್ಟನ್ನು ಸಾರಣಿಗೆಯಿಂದ\nಬೇರ್ಪಡಿಸುವಂತೆ. ನಾವು. ನಮ್ಮ ಮನಸ್ಸೆಂಬ ಸಾರಣಿಗೆಯಿಂದ ನಮ್ಮ ಬಯಕೆಗಳ ಶುದ್ಧೀಕರಣ\nಮಾಡಿಕೊಳ್ಳಬೇಕು. ಆಗ ಅಲ್ಲಿ ಸ್ನೇಹದ ಬೆಸುಗೆ ಇರುತ್ತದೆ. ಅಲ್ಲಿ ಲಕ್ಷ್ಮಿ ಸದಾ ನೆಲೆಸುತ್ತಾಳೆ\".\n\nಇಲ್ಲಿ ಕೃಷ್ಣ ಅರ್ಜುನನಿಗೆ ಯುದ್ಧ ಮಾಡುವಾಗ ಕೂಡಾ ರಾಗ-ದ್ವೇಷವನ್ನು ಮನಸ್ಸಿನಲ್ಲಿ ಇಟ್ಟುಕೊಳ್ಳಬೇಡ,\nಕೇವಲ ನ್ಯಾಯಾನ್ಯಾಯದ ಹೋರಾಟ ಎನ್ನುವ ನಿರ್ಲಿಪ್ತತೆಯಿಂದ ಹೋರಾಡು ಎನ್ನುತ್ತಿದ್ದಾನೆ! ಅಂದರೆ\nದುರ್ಯೋಧನ ಸತ್ತಾಗ ಸಂತೋಷ ಬೇಡ; ಸ್ವಂತ ಮಗ ಅಭಿಮನ್ಯು ಸತ್ತಾಗ ದುಃಖ ಬೇಡ ಎನ್ನುವ\nಯುದ್ಧಪೂರ್ವ ಕಿವಿಮಾತಿದು!\n",
  "3.35": "ಶ್ರೇಯಾನ್‌ ಸ್ವ ಧರ್ಮಃ ವಿಗುಣಃ ಪರಧರ್ಮಾತ್‌ ಸು ಅನುಷ್ಠಿತಾತ್‌ |\n\nಸ್ವಧರ್ಮೇ ನಿಧನಮ್‌ ಶ್ರೇಯಃ ಪರಧರ್ಮಃ ಭಯ ಅವಹಃ - ತನ್ನ ಸ್ವಭಾವಕ್ಕೆ ಪರಕೀಯವಾದ ಧರ್ಮವನ್ನು\nಚೆನ್ನಾಗಿ ಆಚರಿಸುವುದಕ್ಕಿಂತಲೂ, ಅರೆಬರೆಯಾಗಿಯಾದರೂ ಸಹಜ ಧರ್ಮವನ್ನು ಆಚರಿಸುವುದು ಮಿಗಿಲು.\nಸ್ವಭಾವ ಸಹಜ ಧರ್ಮದಲ್ಲಿ ಸಾವಾದರೂ ಮೇಲು. ಪರಕೀಯ ಧರ್ಮ ಅದಕ್ಕಿಂತ ಭಯಂಕರ.\n\nಹಿಂದೆ ಹೇಳಿದಂತೆ ಪ್ರತಿಯೊಂದು ಜೀವಕ್ಕೂ ಅದರದ್ದೇ ಆದ ಸ್ವಭಾವವಿರುತ್ತದೆ ಹಾಗೂ ಅದನ್ನು ಬದಲಿಸಲು\nಬರುವುದಿಲ್ಲ. ಜೀವ ಸ್ವಭಾವಕ್ಕನುಗುಣವಾಗಿ ನಮ್ಮ ಧರ್ಮ, ಅದು ಸ್ವಧರ್ಮ. ಇದು ಸಹಜ ಕ್ರಿಯೆ. ನಮ್ಮ ಸಹಜ\nಸ್ವಭಾವ ಯಾವುದೋ ಅದನ್ನು ನಾವು ಮಾಡಬೇಕೇ ವಿನಃ ಅನ್ಯವನ್ನ ಲ್ದ. ಈ ಕಾರಣಕ್ಕಾಗಿ ತಂದೆ-ತಾಯಿ ತಮ್ಮ\nಅಭಿರುಚಿಯನ್ನು ಮಕ್ಕಳ ಮೇಲೆ ಹೇರದೇ, ಮಕ್ಕಳ ನಿಜ ಸ್ವಭಾವವನ್ನು ಗುರುತಿಸಿ ಅದಕ್ಕನುಗುಣವಾಗಿ ಅವರ\nಭವಿಷ್ಯವನ್ನು ರೂಪಿಸಬೇಕು. ಇಲ್ಲದಿದ್ದರೆ ಅವರ ಭವಿಷ್ಯವನ್ನು ಹಾಳು ಮಾಡಿದಂತಾಗುತ್ತದೆ. ಮಕ್ಕಳ ಪ್ರತಿಭೆ\nಅವರ ಸಹಜವಾದ ಸ್ವಭಾವದಲ್ಲಿದೆ. ಪ್ರತಿಯೊಬ್ಬನೂ ತನ್ನ ಜೀವ ಸ್ವಭಾವಕ್ಕನುಗುಣವಾಗಿ ಕಾರ್ಯ\nನಿರ್ವಹಿಸಬೇಕೇ ಹೊರತು ಇನ್ಯಾರದ್ದೋ ಧರ್ಮವನ್ನು ಅನುಸರಿಸಿ ಅಲ್ಲ. ಇಲ್ಲಿ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ \"ನಿನ್ನ\nಸ್ವಧರ್ಮ ಆಚರಣೆಯಲ್ಲಿ ನ್ಯೂನತೆ ಇದ್ದರೂ, ಅದು ಪರಕೀಯ ಧರ್ಮವನ್ನು ಆಚರಿಸುವುದಕ್ಕಿಂತ ಶ್ರೇಷ್ಠ” ಎಂದು.\nಪರ ಧರ್ಮವನ್ನು ಎಷ್ಟು ಪರಿಪೂರ್ಣವಾಗಿ ಆಚರಿಸಿದರೂ ಅದರಿಂದ ಒಳಿತಿಲ್ಲ, ಅದು ಅಸಹ್ಯ ಅಥವಾ\nಭಯಂಕರ.\n\nಇಲ್ಲಿ ಯುದ್ಧ ಮಾಡುವುದು ಅರ್ಜುನನ ಸ್ವಭಾವ ಧರ್ಮ. ಅದನ್ನು ಬಿಟ್ಟು ಆತ ತಪಸ್ಸು ಮಾಡುವುದಕ್ಕೆ ಕಾಡಿಗೆ\nಹೋಗುವುದು ಆತನ ಸ್ವಧರ್ಮಕ್ಕೆ ವಿರುದ್ಧ. ಆದುದರಿಂದ ಸ್ವಧರ್ಮ ಪಾಲನೆ ಮಾಡು, ರಾಗ ದ್ವೇಷವನ್ನು ಬಿಟ್ಟು\nಹೋರಾಡು ಎನ್ನುತ್ತಿದ್ದಾನೆ ಕೃಷ್ಣ.",
  "3.36": "ಅರ್ಜುನಃ ಉವಾಚ-ಅರ್ಜುನ ಕೇಳಿದನು\nಅಥ ಕೇನ ಪ್ರಯುಕ್ತಃ ಅಯಮ್‌ ಪಾಪಮ್‌ ಚರತಿ ಪೂರುಷಃ |\nಅನಿಚ್ಛನ್‌ ಅಪಿ ವಾರ್ಷೇಯ ಬಲಾತ್‌ ಇವ ನಿಯೋಜಿತಃ-ಓ ವಾರ್ಷೇಯಾ, ಮನುಷ್ಯ ಪಾಪ ಮಾಡುತ್ತಾನೆ. ತನಗೆ\nಇಷ್ಟವಿರದಿದ್ದರೂ ಯಾರೋ ಬಲವಂತದಿಂದ ಮಾಡಿಸಿದಂತೆ! ಇದು ಯಾರ ಪ್ರೇರಣೆ?\n\nಕೃಷ್ಣನ ಉಪದೇಶವನ್ನು ಕೇಳಿದ ಮೇಲೆ ಅರ್ಜುನ ನಮ್ಮ.ನಿಮ್ಮೆಲ್ಲರಿಗೆ ಬರುವಂಥಹ ಒಂದು ಬಹಳ ಮುಖ್ಯವಾದ\nಪ್ರಶ್ನೆಯನ್ನು ಹಾಕುತ್ತಾನೆ. \"ಪಾಪ ಪುಣ್ಯದ ಅರಿವಿದ್ದೂ, ಮಾಡಬಾರದ ಕೆಲಸ ಎಂದು ತಿಳಿದಿದ್ದೂ, ಮನುಷ್ಯ\nಕೆಲವೊಮ್ಮೆ ತಪ್ಪು ಮಾಡುತ್ತಾನೆ-ಇದು ಏಕೆ? ನಮಗೆ ಸರಿ-ತಪ್ಪಿನ ಅರಿವಿದ್ದೂ ಏಕೆ ತಪ್ಪನ್ನು ಮಾಡುತ್ತೇವೆ?",
  "3.37": "ಭಗವಾನುವಾಚ-ಭಗವಂತ ಹೇಳಿದನು:\n\nಕಾಮಃ ಏಷಃ ಕ್ರೋಧಃ ಏಷಃ ರಜಃ ಗುಣ ಸಮುದ್ಧವಃ |\n\nಮಹಾ ಅಶನಃ ಮಹಾಪಾಷ್ಮಾ ವಿದ್ಧಿ ಏನಮ್‌ ಇಹ ವೈರಿಣಮ್‌--ಪಾಪವನ್ನು ಪ್ರೇರೇಪಿಸುವ ಶಕ್ತಿ ಕಾಮ\n(ಕಾಮದ ಅಭಿಮಾನಿಯಾದ ಕಾಲನೇಮಿ) ಇದರದೇ ರೂಪಾಂತರ ಸಿಟ್ಟು. ರಜೋಗುಣದಿಂದ ಇದರ ಹುಟ್ಟು.\nಇದು ತಿಂದಷ್ಟೂ ತಣಿಯದ ಹೊಟ್ಟೆಬಾಕ. ಮಹಾಪಾತಕಗಳ ತವರು. ಇದನ್ನು ಈ ಸಾಧನಾ ಪಥದಲ್ಲಿ\nಹಗೆಯೆಂದು ತಿಳಿ.\n\nಎಲ್ಲವುದಕ್ಕೂ ಮೂಲಕಾರಣ ನಮ್ಮೊಳಗಿರುವ ಬಯಕೆ. ಯಾವುದೋ ಒಂದು ಬಯಕೆ ನಮ್ಮನ್ನು\nಕಾಡುತ್ತಿರುತ್ತದೆ, ಆ ಬಯಕೆಯನ್ನು ತಪ್ಪು ಮಾಡುವ ಮುಖೇನ ಈಡೇರಿಸಿಕೊಳ್ಳಬಹುದು ಎನ್ನುವ ಪ್ರೇರಣೆ\n ನಮ್ಮಲ್ಲಿರುತ್ತದೆ. ಇದನ್ನು ಮಾಡಿಸುವವನು ಕಾಮದ ಅಭಿಮಾನಿಯಾದ ದುಷ್ಟ ಶಕ್ತಿ 'ಕಾಲನೇಮಿ';\nನಮ್ಮೊಳಗೆ ಕಾಲನೇಮಿ ಬಂದು ಕೂತರೆ ನಮಗರಿವಿಲ್ಲದಂತೆ ನಾವು ತಪ್ಪು ಮಾಡುತ್ತೇವೆ. ಮೂಲಭೂತವಾಗಿ\nನೋಡಿದರೆ ಮನುಷ್ಯ ತಪ್ಪು ಮಾಡುವುದಕ್ಕೆ ಎರಡು ಸಂಗತಿಗಳು ಕಾರಣ. ಒಂದು ಅಪೇಕ್ಷೆಗಳು ಹಾಗೂ ಅಪೇಕ್ಷೆ\nಈಡೇರದೇ ಇದ್ದಾಗ ಕೋಪ. ಸಿಟ್ಟಿನ ಬರದಲ್ಲಿ ಮನುಷ್ಯ ಎಷ್ಟು ತಪ್ಪು ಮಾಡುತ್ತಾನೆ ಎಂದು ಹೇಳುವುದೂ ಕಷ್ಟ.\n\nತಪ್ಪು ಮಾಡಿ ಕೊನೆಗೆ ಪಶ್ಚಾತ್ತಾಪ ಪಡುತ್ತೇವೆ. ಈ ಕ್ರೋಧ ಎನ್ನುವುದಕ್ಕೆ ಮೂಲ ಕಾಮ. ಕಾಮವಿಲ್ಲದೆ\nಕ್ರೋಧವಿಲ್ಲ. ಎಲ್ಲಾ ಕ್ರೋಧದ ಹಿಂದೆ ಅರ್ಥಹೀನ ಕಾಮವಿರುತ್ತದೆ.\n\nಮನುಷ್ಯನಲ್ಲಿರುವ ರಜೋಗುಣ ರಾಗ-ದ್ವೇಷವನ್ನು ಬೆಳೆಸುತ್ತದೆ. ಅದಕ್ಕೆ ಎಷ್ಟು ಆಹಾರ ಹಾಕಿದರೂ ಹೊಟ್ಟೆ\nತುಂಬುವುದಿಲ್ಲ! ಇದಕ್ಕೆ ಉತ್ತಮ ಉದಾಹರಣೆ ಎಂದರೆ: ಒಬ್ಬ ಕೆಲಸಕ್ಕಾಗಿ ಅಲೆದಾಡುತ್ತಿರುತ್ತಾನೆ, ಆಗ ಆತನಿಗೆ\nಹೊಟ್ಟೆಪಾಡಿಗೆ ಒಂದು ಕೆಲಸ ಸಿಕ್ಕಿದರೆ ಸಾಕು ಎನ್ನುವ ಅಭಿಪ್ರಾಯವಿರುತ್ತದೆ. ಒಮ್ಮೆ ಕೆಲಸ ಸಿಕ್ಕಿತೆಂದರೆ,\nಆತನ ಬಯಕೆ ಹೆಚ್ಚು ಸಂಬಳ ಪಡೆಯುವತ್ತ ಹರಿಯುತ್ತದೆ. ಹೆಚ್ಚು ಸಿಕ್ಕಿದಾಗ ಮತ್ತಷ್ಟರಾಸೆ, ಹೀಗೆ ಇದು\nಬೆಳೆದುಕೊಂಡು ಹೋಗುತ್ತದೆ. ಎಂದೂ ತೃಪ್ತಿ ಇರುವುದೇ ಇಲ್ಲ.\n\nಹೀಗೆ ನಾವು ತಪ್ಪು ಮಾಡುವುದನ್ನು ಒಗ್ಗಿಸಿಕೊಂಡರೆ ಅದು 'ಮಹಾಶನ' ವಾಗುತ್ತದೆ. ಅದಕ್ಕೆ ಎಷ್ಟು ಔತಣ\nಹಾಕಿದರೂ ಮತ್ತೆ ಬೇಕು ಅನ್ನುತ್ತದೆ. ಎಲ್ಲಿಯವರೆಗೆ ಅಂದರೆ ಅದು ನಮ್ಮಿಂದ ಮಾಡಬಾರದ ಕೆಲಸವನ್ನು\nಮಾಡಿಸುತ್ತದೆ. ತನ್ನ ಆಸೆಯನ್ನು ಈಡೇರಿಸಿಕೊಳ್ಳುವ ಛಲಕ್ಕೆ ಬಿದ್ದವ ಬ್ರಹ್ಮಹತ್ಯೆಗೂ ಹೇಸುವುದಿಲ್ಲ ಎನ್ನುತ್ತದೆ\nಶಾಸ್ತ್ರ! ಆದ್ದರಿಂದ ನಮ್ಮ ಮೊದಲ ಶತ್ರು ರಾಗ-ದ್ವೇಷ. ಅದರ ಬಗ್ಗೆ ಎಚ್ಚರವಹಿಸಬೇಕು. ಅದು ನಿನ್ನೊಳಗಿದ್ದು\nನಿನ್ನನ್ನು ಆಳದಿರಲಿ. ಇದನ್ನೇ ಕುರಾನಿನಲ್ಲಿ ಹೀಗೆ ಹೇಳಿದ್ದಾರೆ \"01೪೮ 17607 ೦೬! 17೦/3 ೧೮1೮ )/೦ 30೮ 0೦೦೧\n61967 ೦೪. ರಾಗ ದ್ವೇಷಗಳು ನಮ್ಮ ವ್ಯಕ್ತಿತ್ವವನ್ನು ಸೂರೆ ಮಾಡಿ ತಾವು ಆಳುತ್ತಿದ್ದಾವಲ್ಲ, ಅವನ್ನು\nಹೊರಗೋಡಿಸು, ನೀನು ನೀನಾಗಿ ಬದುಕು.",
  "3.38": "ಧೂಮೇನ ಅವ್ರಿಯತೇ ವಹ್ನಿಃ ಯಥಾ ಆದರ್ಶಃ ಮಲೇನ ಚ |\n\nಯಥಾ ಉಲ್ದೇನ ಆವೃತಃ ಗರ್ಭಃ ತಥಾ ತೇನ ಇದಮ್‌ ಆವೃತಮ್‌ -ಹೊಗೆಯಿಂದ ಬೆಂಕಿ ಕವಿದಂತೆ\n(ಭಗವಂತ), ಕೊಳೆಯಿಂದ ಕನ್ನಡಿ ಕವಿದಂತೆ(ಮನಸ್ಸು), ಗರ್ಭ ಕೋಶದಿಂದ ಭ್ರೂಣ ಕವಿದಂತೆ(ಜೀವ),\nಕಾಮದಿಂದ ಈ ಎಲ್ಲಾ ಕವಿದುಕೊಂಡಿದೆ.[ಹೊಗೆ ಬೆಂಕಿಯನ್ನು ಕವಿದಂತೆ ಕಾಮ ಸಜ್ಜನರನ್ನು ಕವಿಯುತ್ತದೆ.\nಕೊಳೆ ಕನ್ನಡಿಯನ್ನು ಕೆಡಿಸಿದಂತೆ ಮಧ್ಯಮರನ್ನು. ಗರ್ಭಕೋಶ ಭ್ರೂಣವನ್ನು ಮುಚ್ಚಿದಂತೆ ದುರ್ಜನರನ್ನು]\n\nರಾಗ ದ್ವೇಷಗಳು ಹೇಗೆ ನಮ್ಮ ಕಣ್ಣನ್ನು ಕಟ್ಟುತ್ತವೆ ಎನ್ನುವುದಕ್ಕೆ ಒಂದು ಸುಂದರ ವಿವರಣೆಯನ್ನು ಕೃಷ್ಣ ಇಲ್ಲಿ\nಕೊಟ್ಟಿದ್ದಾನೆ. ಎಲ್ಲವನ್ನೂ ಬೆಳಗುತ್ತಿರುವ ಬೆಂಕಿ, ಅದು ತಾನೂ ಬೆಳಗುತ್ತದೆ ಹಾಗೂ ಎಲ್ಲವನ್ನೂ ಬೆಳಗಿಸುತ್ತದೆ.\nಈ ಬೆಂಕಿಗೆ ಹೊಗೆ ತುಂಬಿದಾಗ ಅದು ಕಾಣುವುದಿಲ್ಲ ಹಾಗೂ ಬೆಳಗುವುದಿಲ್ಲ. ಭಗವಂತ ಬೆಂಕಿಯಂತೆ. ನಮ್ಮ\nರಜೋ ಗುಣ ಹೊಗೆಯಂತೆ. ನಮಗೂ ಭಗವಂತನಿಗೂ ನಡುವೆ. ರಜೋಗುಣದ ಪರದೆ ಬೆಂಕಿಯನ್ನು ಸುತ್ತಿದ\nಹೊಗೆಯಂತೆ. ಇದು ಸಾತ್ವಿಕ ಮನುಷ್ಯನಿಗೆ ಕೃಷ್ಣ ಕೊಟ್ಟ ದೃಷ್ಟಾಂತ. ಇನ್ನು ರಾಜಸರಿಗೆ ಕೃಷ್ಣ ಕೊಡುವ\nದೃಷ್ಟಾಂತ ಮಸಿ ಬಳಿದ ಕನ್ನಡಿ. ಮನಸ್ಸು ಎನ್ನುವ ಕನ್ನಡಿಗೆ ರಜೋಗುಣ ಎನ್ನುವ ಕೊಳೆ ಬಳಿದಂತೆ ಎನ್ನುತ್ತಾನೆ\n\nಕೃಷ್ಣ. ತಾಮಸರಿಗೆ ಕೃಷ್ಣನ ದೃಷ್ಟಾಂತ ಗರ್ಭಚೀಲದಲ್ಲಿರುವ ಭ್ರೂಣ. ಎಲ್ಲವೂ ಕತ್ತಲು. ಕಣ್ಣು ತೆರೆದರೂ ಕಾಣದು,\nಜೀವಜಾತವೆನ್ನುವ ಮರಿಯನ್ನು ರಜೋಗುಣ ಎನ್ನುವ ಮೊಟ್ಟೆಯಲ್ಲಿಟ್ಟಂತೆ.\n\nಹೀಗೆ ಬೆಂಕಿಗೆ ಹೊಗೆಯಂತೆ-ಭಗವಂತನಿಗೆ ಆವರಣ ಈ ರಜೋ ಗುಣ; ಕನ್ನಡಿಗೆ ಹಚ್ಚಿದ ಮಸಿಯಂತೆ-\nಅಂತಃಕಾರಣಕ್ಕೆ ಆವರಣ ಈ ರಜೋಗುಣ. ಅಂತಃಕರಣ ಕೆಲಸ ಮಾಡದೇ ಇದ್ದಾಗ ಭಗವಂತ ಕಾಣುವುದಿಲ್ಲ\nಆಗ- ಜೀವಕ್ಕೆ 'ಭ್ರೂಣದಂತೆ' ಎಲ್ಲವೂ ಕತ್ತಲು. ಎಲ್ಲವೂ ಇದ್ದೂ ಏನೂ ಉಪಯೋಗವಿಲ್ಲದೆ ವ್ಯರ್ಥವಾಗುತ್ತದೆ.\n",
  "3.39": "ಆವೃತಮ್‌ ಜ್ಞಾನಮ್‌ ಏತೇನ ಜ್ಞಾನಿನಃ ನಿತ್ಯವೈರಿಣಾ |\n\nಕಾಮ ರೂಪೇಣ ಕೌಂತೇಯ ದುಷ್ಬೂರೇಣ ಅನಲೇನ ಚ -- ಓ ಕೌಂತೇಯಾ, ಬೆಂಕಿಯಂತೆ ಕಬಳಿಸಿದಷ್ಟೂ\nತೃಪ್ತಿಯಿಲ್ಲದೆ, ಕೊನೆಯಿಲ್ಲದ ಈ ಕಾಮವೆಂಬುದು ಸಾಧಕನ ಚಿರಶತ್ರು. ಇದು ಬಲ್ಲವರ ತಿಳಿವನ್ನೂ ಕವಿದು\nಮಂಕಾಗಿಸುತ್ತದೆ.\n\nಈ ರಜೋಗುಣದ ಪರದೆ- ಜ್ಞಾನ ಬಂದವನಿಗೆ ಇದ್ದ ಜ್ಞಾನ ಉಪಯೋಗವಾಗದಂತೆ, ಜ್ಞಾನವಿಲ್ಲದವನಿಗೆ ಜ್ಞಾನ\nಬರದಂತೆ-ತಡೆಗೋಡೆಯಾಗಿ ನಿಲ್ಲುತ್ತದೆ. ರಾಗ-ದ್ವೇಷ ನಮ್ಮ ಕಡು ವೈರಿ. ಅದು ಎಷ್ಟು ಭಯಂಕರ ಎಂದರೆ\nಅದನ್ನು 'ಬಯಕೆಯ ಬೆಂಕಿ' ಎನ್ನಬಹುದು. ಅದಕ್ಕೆ ಎಷ್ಟು ಬಡಿಸಿದರೂ ಅದು ಸಾಕು ಎನ್ನದು. ಕುಂತಿಯಂತಹ\nಮಹಾ ತಾಯಿಯ ಮಗನಾದ ನೀನು ಈ ಕಾಮ(ಬಯಕೆ, ಓ ಕೌಂತೇಯ ಎನ್ನು ವ ಜ್ಞಾನ ವಿರೋಧಿ ಶತ್ರುವನ್ನು\nತಿಳಿ ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.\n\nಇಲ್ಲಿ ನಮಗೆ ನಮ್ಮ ನಿಜ ವೈರಿ ನಮ್ಮ ಕಾಮ ಅಥವಾ ಬಯಕೆ, ಅಥವಾ ರಾಗ-ದ್ವೇಷ ಎಂದು ತಿಳಿಯಿತು.\nಹಾಗಿದ್ದರೆ ಈ ವೈರಿಯ ನೆಲೆ ಯಾವುದು? ಇದನ್ನು ಕೃಷ್ಣ ಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ವಿವರಿಸಿದ್ದಾನೆ.\n",
  "3.40": "ಇಂದ್ರಿಯಾಣಿ ಮನಃ ಬುದ್ಧಿಃ ಅಸ್ಯ ಅಧಿಷ್ಠಾನಮ್‌ ಉಚ್ಯತೇ |\nಏತೈಃ ವಿಮೋಹಯತಿ ಏಷಃ ಜ್ಞಾನಮ್‌ ಆವೃತ್ಯ ದೇಹಿನಮ್‌ -- ಇಂದ್ರಿಯಗಳು, ಮನಸ್ಸು, ಬುದ್ಧಿ ಈ ಕಾಮದ\nನೆಲೆದಾಣಗಳು. ಇವುಗಳ ಮೂಲಕ ಇದು ತಿಳಿವನ್ನು ಕವಿದು ಸಾಧಕನನ್ನು ಕಂಗೆಡಿಸುತ್ತದೆ.\n\nನಮ್ಮ ಬಯಕೆಗಳ ಸರಮಾಲೆ ಮೊದಲು ಬಂದು ಕೂರುವುದು ನಮ್ಮ ಇಂದ್ರಿಯದಲ್ಲಿ. ಕಣ್ಣಿಗೆ ನೋಡುವ, ಕಿವಿಗೆ\nಕೇಳುವ, ಮೂಗಿಗೆ ಮೂಸುವ, ಮೈಗೆ ಮುಟ್ಟುವ-ಹೀಗೆ ಒಂದೊಂದು ಬಯಕೆ ಒಂದೊಂದು ರೂಪದಲ್ಲಿ\nಒಂದೊಂದು ಇಂದ್ರಿಯದಲ್ಲಿ ಬಂದು ಕೂರುತ್ತದೆ. ಅಲ್ಲಿ ನಾವು ಅದನ್ನು ನಿಗ್ರಹಿಸದೇ ಇದ್ದರೆ. ಅದು ನಮ್ಮ\n\nಮನಸ್ಸನ್ನು ಆಕ್ರಮಿಸುತ್ತದೆ. . ಅಲ್ಲೂ ನಾವು ಸಡಿಲಗೊಳಿಸಿದರೆ ಅದು ಮುಂದೆ ನಮ್ಮ ಬುದ್ಧಿಯನ್ನು\nಆಕ್ರಮಿಸಿಬಿಡುತ್ತದೆ. ಹೀಗೆ ಅಂಗಳದ(ಇಂದ್ರಿಯ) ಈ ಶತ್ರುವನ್ನು ಮೊಗಸಾಲೇ(ಮನಸ್ಸು)ಗೆ ಕರೆದು, ನಂತರ\nನಮ್ಮ ನಡು ಮನೆಯಲ್ಲಿ(ಬುದ್ಧಿ) ಕುಳ್ಳಿರಿಸಿದಂತೆ. ಒಮ್ಮೆ ಈ ಶತ್ರು ನಮ್ಮ ಬುದ್ಧಿಯನ್ನು ಆಕ್ರಮಿಸಿದರೆ ಮುಂದೆ\nಅದನ್ನು ತೊಡೆದು ಹಾಕುವುದು ತುಂಬಾ ಕಷ್ಟ. ಈ ಸ್ಥಿತಿಯಲ್ಲಿ ಬಯಕೆ ಎನ್ನುವುದು ಸಿದ್ಧಾಂತವಾಗಿ ನಮ್ಮೊಳಗಿದ್ದು\nನಮ್ಮನ್ನೇ ಆಳುವುದಕ್ಕೆ ಆರಂಭಿಸುತ್ತದೆ. ಇದರಿಂದ ಕಾಮನೆ ಎನ್ನುವುದು ನಮ್ಮ ಜೀವನ ಧರ್ಮವಾಗುತ್ತದೆ.\nಉದಾಹರಣೆಗೆ ಒಂದು ಸಂಗತಿ ನಮ್ಮ ಕಿವಿ ಮೇಲೆ ಬೀಳುತ್ತದೆ. ನಾವು ಆ ವಿಷಯದಿಂದ ನಮಗೇನು\nಉಪಯೋಗ ಆ ಬಗ್ಗೆ ಗಮನ ಏಕೆ ಹರಿಸಬೇಕು ಎಂದು ಯೋಚಿಸುವುದಿಲ್ಲ. ಅದನ್ನು ಬಿಟ್ಟು ಕೇಳಿದ ವಿಷಯವನ್ನು\nನೋಡಲು ಹಂಬಲಿಸುತ್ತೇವೆ. ನೋಡಿದ ಮೇಲೆ ಮುಟ್ಟಬೇಕು(ತಿನ್ನಬೇಕು ಮೂಸಬೇಕು ಇತ್ಯಾದಿ) ಎನ್ನುವ ಆಸೆ!\nಹೀಗೆ ನಾವು ನಮ್ಮೆಲ್ಲಾ ಇಂದ್ರಿಯದಲ್ಲಿ ಈ ಕಾಮನೆ ಎನ್ನುವ ವೈರಿಗೆ ಪ್ರೋತ್ಸಾಹ ಕೊಡುತ್ತೇವೆ. ಆಗ ಅದು\nನಿಧಾನವಾಗಿ. ನಮ್ಮ ಮನಸ್ಸನ್ನು ಆಕ್ರಮಿಸುತ್ತದೆ. ಮನಸ್ಸು ನಿರಂತರವಾಗಿ ಆ ವಿಷಯದ ಬಗ್ಗೆ\nಯೋಚಿಸಲಾರಂಜಭಿಸುತ್ತದೆ. ಮನಸ್ಸು 'ಅದು ನನ್ನ ದಾಗಬೇಕು, ನನ್ನ ದೇ ಆಗಬೇಕು ' ಎಂದು\nಯೋಚಿಸುತ್ತಿದೆ ಎಂದರೆ ಈ ವೈರಿ ಮನಸ್ಸನ್ನು ಆಕ್ರಮಿಸಿದೆ ಎಂದರ್ಥ. ಇಲ್ಲಿಂದ ಮುಂದೆ ಬುದ್ಧಿ; 'ಅದನ್ನು ಬಿಟ್ಟು\nನಾನಿರಲಾರೆ, ಏನೇ ಆಗಲಿ ನಾನು ಅದನ್ನು ಪಡೆಯಲೇ ಬೇಕು' ಇತ್ಯಾದಿ ಯೋಚನೆಗಳು, ಇದು ಕಾಮನೆ ನಮ್ಮ\nಬುದ್ಧಿಯನ್ನು ಆಕ್ರಮಿಸುವ ಸೂಚನೆ. ಇದು ಸರ್ವನಾಶದ ಮುನ್ಸೂಚನೆ. ಹೀಗೆ ಜ್ಞಾನಕ್ಕೆ ವಿಭ್ರಮೆಯಾಗಿರುವ ಈ\nಮೂರು ಜಾಗದಲ್ಲಿ ಕೂತು ಜ್ಞಾನಕ್ಕೆ ಪರದೆಯಾಗಿ ನಿಲ್ಲುತ್ತದೆ ಈ ನಮ್ಮ ವೈರಿ.\n\nಇಲ್ಲಿ 'ದೇಹಿನಮ್‌' ಎನ್ನುವ ಪದ ಬಳಕೆಯಾಗಿದೆ. ನಮ್ಮ ದೇಹ ಎನ್ನುವುದು ಜ್ಞಾನದ ಮೂಲಕ ನಮ್ಮನ್ನು\nಎತ್ತರಕ್ಕೆ ಕೊಂಡೊಯ್ಯುವ ಸಾಧನ. ಆದರೆ ಕಾಮನೆ ಎನ್ನುವ ವೈರಿಯ ಸಂಗ ಮಾಡಿದಾಗ ಅದು ನಮ್ಮನ್ನು\nಅಧಃಪಾತಕ್ಕೆ ತಳ್ಳುವ ಸಾಧನವಾಗುತ್ತದೆ. ಇದು ಈ ಪದದ ಹಿಂದಿರುವ ಭಾವಾರ್ಥ.\n\nಹೀಗೆ ನಮ್ಮ ವೈರಿ ಯಾರು, ಆತ ಇರುವ ಸ್ಥಾನ ಯಾವುದು ಹಾಗೂ ಆತ ಹೇಗೆ ನಮ್ಮನ್ನು ಆಕ್ರಮಿಸುತ್ತಾನೆ\nಎನ್ನುವ ವಿವರಣೆಯನ್ನು ಕೊಟ್ಟ ಕೃಷ್ಣ, ಈ ವೈರಿಯನ್ನು ಗೆದೆಯುವ ಪರಿಯನ್ನು ಮುಂದೆ ವಿವರಿಸುತ್ತಾನೆ.\n",
  "3.41": "ತಸ್ಮಾತ್‌ ತ್ವಮ್‌ ಇಂದ್ರಿಯಾಣಿ ಆದೌ ನಿಯಮ್ಯ ಭರತ ಋಷಭ |\n\nಪಾಪ್ಮಾನಮ್‌ ಪ್ರಜಹಿ ಹಿ ಏನಮ್‌ ಜ್ಞಾನ ವಿಜ್ಞಾನ ನಾಶನಮ್‌- ಆದ್ದರಿಂದ, ಓ ಭರತವಂಶದ ವೀರಾ, ಮೊದಲು\nನೀನು ಇಂದ್ರಿಯಗಳನ್ನು ಹದ್ದಿನಲ್ಲಿರಿಸಿಕೊಂಡು, ಅರಿವನ್ನೂ ಆಳವಾದ ಚಿಂತನ ಶಕ್ತಿಯನ್ನೂ ಹಾಳು ಗೆಡವಬಲ್ಲ\nಈ ಪಾಪಿಯನ್ನು ಒದ್ದೋಡಿಸು.\n\nಇಂತಹ ಮಹಾ ವೈರಿಯನ್ನು ನಾವು ಮೊದಲ ಹಂತದಲ್ಲೇ ನಿಯಂತ್ರಿಸಬೇಕು. ಈ ಶತ್ರುವಿನ ಮೊದಲ ಪ್ರವೇಶ\nದ್ವಾರವಾದ ಇಂದ್ರಿಯದಲ್ಲೇ ಅದರ ನಿಯಂತ್ರಣ ಮಾಡಬೇಕು. ನಮ್ಮ ಜ್ಞಾನ(ಶ್ರವಣ)ವನ್ನು, ವಿಜ್ಞಾನಮನನ-\n\nನಿಧಿಧ್ಯಾಸನ)ವನ್ನು ಹಾಳುಗೆಡವಿ, ನಮ್ಮ ಚಿಂತನಾ ಶಕ್ತಿಯನ್ನು ನಾಶಮಾಡಬಲ್ಲ ಈ ಮಹಾ ಪಾಪಿಯನ್ನು\nಒದ್ದೋಡಿಸು ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಆದರೆ ಹೇಗೆ? ಇದಕ್ಕೆ ಯಾರು ಸಹಾಯ ಮಾಡುತ್ತಾರೆ ? ಮುಂದೆ ಕೇಳಿ!\n",
  "3.42": "ಇಂದ್ರಿಯಾಣಿ ಪರಾಣಿ ಆಹುಃ ಇಂದ್ರಿಯೇಭ್ಯಃ ಪರಮ್‌ ಮನಃ ।\n\nಮನಸಃ ತು ಪರಾ ಬುದ್ಧಿಃ ಯಃ ಬುದ್ಧೇಃ ಪರತಃ ತು ಸಃ-ಇಂದ್ರಿಯಗಳು[ಶರೀರಕ್ಕಿಂತ] ಹಿರಿದಾದ ತಾಣಗಳು.\n[ಇಂದ್ರಿಯಾಭಿಮಾನಿಗಳಾದ ಇಂದ್ರಾದಿಗಳು ಹಿರಿಯ ದೇವತೆಗಳು].ಇಂದ್ರಿಯಗಳಿಗಿಂತ ಮನಸ್ಸು ಹಿರಿಯ\nತಾಣ.[ಇಂದ್ರಿಯಾಭಿಮಾನಿ ದೇವತೆಗಳಿಗಿಂತ ಮನೋಭಿಮಾನಿ ರುದ್ರ ಹಿರಿಯ ದೇವತೆ]. ಮನಸ್ಸಿಗಿಂತ ಬುದ್ಧಿ\nಹಿರಿಯ ತಾಣ[ಮನೋಭಿಮಾನಿಗಿಂತ ಬುದ್ಧಿಮಾನಿನಿ ಸರಸ್ವತಿ ಹಿರಿಯ ದೇವತೆ]... ಬುದ್ಧಿಗಿಂತಲೂ\nಆಚೆಗಿರುವಂತಾದ್ದು ಆ ಪರತತ್ವ[ಬುದ್ಧಿ ಮಾನಿನಿಗಿಂತಲೂ ಬುದ್ಧಿಗೋಚರನಾಗದ ಭಗವಂತ ಹಿರಿಯತತ್ವ].\n\nಹೇಗೆ ದುಷ್ಟ ಶಕ್ತಿಗಳಿವೆಯೋ ಹಾಗೇ ನಮ್ಮ ಒಳಿತನ್ನು ಬಯಸುವ ದೇವತಾಶಕ್ತಿಗಳು ನಮ್ಮ ರಕ್ಷಣೆಗೆ\nನಿಂತಿರುತ್ತಾರೆ. ಪ್ರತಿಯೊಂದು ಇಂದ್ರಿಯಗಳಿಗೂ ಒಬ್ಬ ದೇವತೆ ಅಭಿಮಾನಿ. ನಮ್ಮ ಇಂದ್ರಿಯದ\nಅಭಿಮಾನಿದೇವತೆ ಇಂದ್ರ. ಮನಸ್ಸಿನ ಅಭಿಮಾನಿ ಶಿವ-ಪಾರ್ವತಿಯರು, ಬುದ್ಧಿಯ ಅಭಿಮಾನಿ ಸರಸ್ವತಿ.\nಬುದ್ಧಿಯಿಂದಾಚೆಗಿರುವುದು ಆತ್ಮ-ಅದುವೇ ಆ ಭಗವಂತನ ಸ್ಥಾನ.\n\nನಾವು ನಮ್ಮ ಇಂದ್ರಿಯ ಮನಸ್ಸು ಬುದ್ಧಿಯನ್ನು ನಿಯಂತ್ರಿಸುವ ದೇವತಾ ಶಕ್ತಿಗೆ ಶರಣಾಗಬೇಕು. ಆಗ ಆ\nದೇವತಾ ಶಕ್ತಿಗಳ ಸಹಾಯದಿಂದ ನಾವು ಜ್ಞಾನವನ್ನು ಪಡೆದು ಭಗವಂತನನ್ನು ಕಾಣಬಹುದು. ನಮ್ಮ\nಪ್ರತಿಯೊಂದು ಇಂದ್ರಿಯಕ್ಕೂ ಒಬ್ಬ ಅಭಿಮಾನಿ ದೇವತೆ ಇದ್ದಾನೆ. ಕಣ್ಣಿಗೆ ಸೂರ್ಯ, ಕಿವಿಗೆ ಚಂದ್ರ, ಬಾಯಿಗೆ\nಅಗ್ನಿ, ನಾಲಿಗೆಗೆ-ವರುಣ, ಮೂಗಿಗೆ-ಆಶ್ವೀದೇವತೆಗಳು ,ಕೈಗೆ-ಇಂದ್ರ(ಈತ ಸರ್ವೇಂದ್ರಿಯದ ಒಡೆಯ ಕೂಡಾ\nಹೌದು), ಕಾಲಿಗೆ-ಇಂದ್ರ ಪುತ್ರ ಉಪೇಂದ್ರ, ಯಮ-ಮಲಮೂತ್ರ ವಿಸರ್ಜನಾಂಗದ ಮತ್ತು ದಕ್ಷ ಸಂತಾನಕ್ಕೆ\nಸಂಬಂಧಪಟ್ಟ ಅಂಗದ ದೇವತೆ. ಹೀಗೆ ಪ್ರತಿಯೊಂದು ದೇವತೆಗಳೂ ನಮಗೆ ನಮ್ಮ ಶತ್ರುವಿನಿಂದ ಪಾರಾಗಲು\nಸಹಾಯ ಮಾಡುತ್ತಾರೆ. ಹೀಗೆ ದೇವತೆಗಳನ್ನು ಪ್ರಾರ್ಥಿಸಿ ಅವರ ಸಹಾಯ ಪಡೆದು ದುಷ್ಟ ಶಕ್ತಿಯಿಂದ ದೂರ\nಸರಿದು ಎಲ್ಲಕ್ಕೂ ಮಿಗಿಲಾದ ಆ ಪರತತ್ವವನ್ನು ಸೇರಬೇಕು.\n\nಕ\nಜಹಿ ಶತ್ರುಂ ಮಹಾಬಾಹೋ ಕಾಮರೂಪಂ ದುರಾಸದಮ್‌ ॥ಇಷ೩॥\n\nಏವಂ ಬುದ್ಧೇಃ ಪರಂ ಬುದ್ಧ್ವಾ ಸಂಸ್ಕ್ತಭ್ಕಾ ತ್ಮಾನಮಾತ್ಮನಾ।\n\nಏವಮ್‌ ಬುದ್ಧೇಃ ಪರಮ್‌ ಬುದ್ಧ್ವಾ ಸಂಸ್ತಭ್ಯ ಆತ್ಮಾನಮ್‌ ಆತ್ಮಾನಾ |\nಜಹಿ ಶತ್ರುಮ್‌ ಮಹಾ ಬಾಹೋ ಕಾಮರೂಪಮ್‌ ದುರಾಸದಮ್‌-ಓ ಮಹಾವೀರ, ಹೀಗೆ ಬುದ್ಧಿಗೂ ನಿಲುಕದ ಆ\n\nಪರತತ್ವವನ್ನು ತಿಳಿದು, ವಿವೇಕದಿಂದ ಬಗೆಯನ್ನು ಬಿಗಿಹಿಡಿದು, ಸಾಮಾನ್ಯರಿಗೆ ಬಗ್ಗದ ಕಾಮವೆಂಬ ಹಗೆಯನ್ನು\nಒದ್ದೋಡಿಸು.\n\nಹೀಗೆ ಇಂದ್ರಿಯ-ಮನಸ್ಸು-ಬುದ್ಧಿಗೆ ನಿಲುಕದ ಆ ಪರತತ್ವವನ್ನು ತಿಳಿದು, ಮನಸ್ಸೆಂಬ ಚಂಚಲವಾದ ಕುದುರೆಗೆ\nಬುದ್ಧಿಯೆಂಬ ಲಗಾಮನ್ನು ಕಟ್ಟಿ, ಆ ಕಡಿವಾಣವನ್ನು ಭಗವಂತನ ಕೈಯಲ್ಲಿ ಕೊಟ್ಟು, ಸರ್ವ ದೇವತೆಗಳ\nಸಹಾಯದಿಂದ ಕಾಲನೇಮಿ ಎನ್ನುವ ರಾಕ್ಷಸನನ್ನು ಹಂತ ಹಂತವಾಗಿ ಗೆದ್ದು, ಭಗವಂತನನ್ನು ಸೇರು ಎನ್ನುತ್ತಾನೆ\nಕೃಷ್ಣ. ಇಲ್ಲಿ ಹೇಳಿದ ವಿವರಣೆಯನ್ನು ನಮಗೆ ಕೆಟ್ಟ ಬಯಕೆ ಹುಟ್ಟಿದಾಗ ನೆನಪಿಸಿಕೊಂಡರೆ ಕಾಲನೇಮಿ ಎನ್ನುವ\nರಾಕ್ಷಸ ನಮ್ಮೊಳಗೆ ನುಸುಳದಂತೆ ತಡೆಯಬಹುದು. ಏಕೆಂದರೆ ಎಲ್ಲಾ ಬಯಕೆಗಳೂ ಕೆಟ್ಟದ್ದಲ್ಲ. ಭಗವಂತನನ್ನು\nಸೇರಬೇಕು ಎನ್ನುವ ಬಯಕೆ ಬೇಕು. ಆದ್ದರಿಂದ ನಮ್ಮ ಬುದ್ಧಿಯನ್ನು ಭಗವಂತನ ಕೈಗೊಪ್ಪಿಸಿ, ದುಷ್ಟ\nಕಾಮನೆಗಳ ವಿರುದ್ಧ ದೇವತೆಗಳ ಸಹಾಯದಿಂದ ಹೋರಾಡಿ ಮೋಕ್ಷವನ್ನು ಪಡೆಯಬಹುದು. ಇಲ್ಲಿ ಒಂದು\nಎಚ್ಚರ ಅಗತ್ಯ, ಒಂದೇ ಸಲ ಈ ದುಷ್ಟ ಶಕ್ತಿಯ ವಿರುದ್ಧ ಹೋರಾಡಿ ಜಯ ಗಳಿಸುತ್ತೇನೆ ಎಂದರೆ ಅದು ಅಸಾಧ್ಯ.\nಇದನ್ನು ಹಂತ ಹಂತವಾಗಿ ಗಳಿಸಬೇಕು. ಸಾಧನೆಯ ವಿವಿಧ ಮೆಟ್ಟಲಿನಲ್ಲಿ ವಿವಿಧ ದೇವತೆಗಳು ನಮಗೆ\nಸಹಾಯ ಮಾಡುತ್ತಾರೆ.\n\nಇತಿ ತೃತೀಯೋಧ್ಯಾಯಃ\nಮೂರನೇ ಅಧ್ಯಾಯ ಮುಗಿಯಿತು\n\nಅಧ್ಯಾಯ ನಾಲ್ಕು\n\nಹಿಂದೆ ಕೃಷ್ಣ ಜ್ಞಾನಮಾರ್ಗ ಮತ್ತು ಕರ್ಮಮಾರ್ಗದ ಬಗ್ಗೆ ಎರಡನೇ ಅಧ್ಯಾಯದಲ್ಲಿ ಪ್ರಸ್ತಾಪಿಸಿ, ಆ ನಂತರ\nಮೂರನೇ ಅಧ್ಯಾಯದಲ್ಲಿ ಕರ್ಮಯೋಗದ ವಿಸ್ತಾರವನ್ನು ತಿಳಿಸಿದ. ನಾಲ್ಕನೇ ಅಧ್ಯಾಯದಲ್ಲಿ ಭಗವಂತನ\nಜ್ಞಾನದ ಅರಿವಿನ ಮುಖ ಮತ್ತು ಕರ್ಮದ ಪ್ರಭೇದಗಳನ್ನು ಕೃಷ್ಣ ವಿವರಿಸುತ್ತಾನೆ. ಹಿಂದೆ ಹೇಳಿದ ಜ್ಞಾನಯೋಗ\nಮತ್ತು ಕರ್ಮಯೋಗವನ್ನೇ ವಿಸ್ತರಿಸಿ ಜ್ಞಾನದ ಮಹತ್ವ ಮತ್ತು ಕರ್ಮದ ಪ್ರಭೇದಗಳ ಜೊತೆಗೆ ಈ ಎರಡು\nಮಾರ್ಗದಿಂದ ನಾವು ಪಡೆಯತಕ್ಕಂತಹ ಭಗವಂತನ ಮಹಿಮೆ- ಇದನ್ನು ಈ ಅಧ್ಯಾಯದಲ್ಲಿ ವಿವರಿಸಲಾಗಿದೆ. ಈ\nಅಧ್ಯಾಯ ಕೃಷ್ಣನ ಮಾತಿನೊಂದಿಗೆ ಆರಂಭವಾಗುತ್ತದೆ.\n\nಭಗವಾನುವಾಚ ।\nಇಮಂ ವಿವಸ್ವತೇ ಯೋಗಂ ಪ್ರೋಕ್ತವಾನಹಮವ್ಯಯಮ್‌ |\nವಿವಸ್ವಾನ್‌ ಮನವೇ ಪ್ರಾಹ ಮನುರಿಕ್ಷಾ ಕವೇ$ಬ್ರವೀತ್‌.. ॥೧॥\n\nಭಗವಾನ್‌ ಉವಾಚ-ಭಗವಂತ ಹೇಳಿದನು:\n\nಇಮಮ್‌ ವಿವಸ್ವತೇ ಯೋಗಮ್‌ ಪ್ರೋಕ್ತವಾನ್‌ ಅಹಮ್‌ ಅವ್ಯಯಮ್‌ |\n\nವಿವಸ್ವಾನ್‌ ಮನವೇ ಪ್ರಾಹ ಮನುಃ ಇಕ್ಷ್ವಾಕವೇ ಅಬ್ರವೀತ್‌ -ಅಳಿವಿರದ ಈ ಸಾಧನಾ ಮಾರ್ಗವನ್ನು ನಾನು\nಸೂರ್ಯನಿಗೆ ಹೇಳಿದ್ದೆ. ಸೂರ್ಯ ಮನುವಿಗೆ ಹೇಳಿದ್ದ. ಮನು ಇಕ್ಷಾಕುವಿಗೆ ಹೇಳಿದ್ದ.\n\nಏವಂ ಪರಂಪರಾಪ್ರಾಪ್ರಮಿಮಂ ರಾಜರ್ಷಯೋವಿದುಃ |\nಸಕಾಲೇನೇಹ ಮಹತಾ ಯೋಗೋ ನಷ್ಟಃ ಪರಂತಪ॥೨॥\n\nಏವಮ್‌ ಪರಂಪರಾ ಪ್ರಾಪ್ತಮ್‌ ಇಮಮ್‌ ರಾಜ ಖುಷಯ: ವಿದುಃ |\n\nಸಃ ಕಾಲೇನ ಇಹ ಮಹತಾ ಯೋಗಃ ನಷ್ಟಃ ಪರಂತಪ-ಹೀಗೆ ಒಬ್ಬರಿಂದ ಒಬ್ಬರಿಗೆ ಹರಿದು ಬಂದಿರುವ ಇದನ್ನು\nಜ್ಞಾನಿಗಳಾದ ಅರಸರು ಅರಿತಿದ್ದರು. ಓ ಅರಿಗಳನ್ನು ತರಿದವನೇ, ತುಂಬಾ ಕಾಲದ ಬಳಿಕ ಆ ಅರಿವಿನ ದಾರಿ ಈ\nನೆಲದಲ್ಲಿ ಕಣ್ಮರೆಯಾಯಿತು.\n\nಸಏವಾಯಂ ಮಯಾ ತೇಂದ್ಯ ಯೋಗಃ ಪ್ರೋಕ್ತಃ ಪುರಾತನಃ।\nಭಕ್ತೋಸಿ ಮೇ ಸಖಾ ಚೇತಿ ರಹಸ್ಯಂ ಹ್ಯೇತದುತ್ತಮಮ್‌ ॥೩ಿ॥\n\nಸಃ ಏವ ಅಯಮ್‌ ಮ",
  "3.43": "[ಬನ್ನಂಜೆಯವರ ಭಾಷ್ಯದಲ್ಲಿ ಮೂರನೇ ಅಧ್ಯಾಯವು ೪೨ ಶ್ಲೋಕಗಳೊಂದಿಗೆ ಮುಕ್ತಾಯಗೊಳ್ಳುತ್ತದೆ. ೩.೪೩ನೆಯ ಶ್ಲೋಕದ ವಿವರಣೆಯು ಹಿಂದಿನ ಶ್ಲೋಕದಲ್ಲೇ ಅಡಕವಾಗಿದೆ. ಅಧ್ಯಾಯದ ಉಪಸಂಹಾರ: ಕಾಮರೂಪಿಯಾದ ಶತ್ರುವನ್ನು ಜಯಿಸು ಎಂದಷ್ಟೇ.]",
  "4.1": "ಭಗವಾನ್‌ ಉವಾಚ-ಭಗವಂತ ಹೇಳಿದನು:\n\nಇಮಮ್‌ ವಿವಸ್ವತೇ ಯೋಗಮ್‌ ಪ್ರೋಕ್ತವಾನ್‌ ಅಹಮ್‌ ಅವ್ಯಯಮ್‌ |\n\nವಿವಸ್ವಾನ್‌ ಮನವೇ ಪ್ರಾಹ ಮನುಃ ಇಕ್ಷ್ವಾಕವೇ ಅಬ್ರವೀತ್‌ -ಅಳಿವಿರದ ಈ ಸಾಧನಾ ಮಾರ್ಗವನ್ನು ನಾನು\nಸೂರ್ಯನಿಗೆ ಹೇಳಿದ್ದೆ. ಸೂರ್ಯ ಮನುವಿಗೆ ಹೇಳಿದ್ದ. ಮನು ಇಕ್ಷಾಕುವಿಗೆ ಹೇಳಿದ್ದ.\n\nಏವಂ ಪರಂಪರಾಪ್ರಾಪ್ರಮಿಮಂ ರಾಜರ್ಷಯೋವಿದುಃ |\nಸಕಾಲೇನೇಹ ಮಹತಾ ಯೋಗೋ ನಷ್ಟಃ ಪರಂತಪ॥೨॥",
  "4.2": "ಏವಮ್‌ ಪರಂಪರಾ ಪ್ರಾಪ್ತಮ್‌ ಇಮಮ್‌ ರಾಜ ಋಷಯಃ ವಿದುಃ |\n\nಸಃ ಕಾಲೇನ ಇಹ ಮಹತಾ ಯೋಗಃ ನಷ್ಟಃ ಪರಂತಪ-ಹೀಗೆ ಒಬ್ಬರಿಂದ ಒಬ್ಬರಿಗೆ ಹರಿದು ಬಂದಿರುವ ಇದನ್ನು\nಜ್ಞಾನಿಗಳಾದ ಅರಸರು ಅರಿತಿದ್ದರು. ಓ ಅರಿಗಳನ್ನು ತರಿದವನೇ, ತುಂಬಾ ಕಾಲದ ಬಳಿಕ ಆ ಅರಿವಿನ ದಾರಿ ಈ\nನೆಲದಲ್ಲಿ ಕಣ್ಮರೆಯಾಯಿತು.",
  "4.3": "ಸಃ ಏವ ಅಯಮ್ ಮಯಾ ತೇ ಅದ್ಯ ಯೋಗಃ ಪ್ರೋಕ್ತಃ ಪುರಾತನಃ |\nಭಕ್ತಃ ಅಸಿ ಮೇ ಸಖಾ ಚ ಇತಿ ರಹಸ್ಯಂ ಹಿ ಏತತ್ ಉತ್ತಮಮ್ -- ಅದೇ ಪುರಾತನವಾದ ಯೋಗವನ್ನು ಇಂದು ನಿನಗೆ ಹೇಳಿದ್ದೇನೆ. ನೀನು ನನ್ನ ಭಕ್ತ ಮತ್ತು ಸಖ ಎಂಬ ಕಾರಣದಿಂದ. ಇದು ಅತ್ಯಂತ ಶ್ರೇಷ್ಠವಾದ ರಹಸ್ಯ.\n\n[BG 4.3 marker appears at the bottom of the chapter-opening page; full commentary continues on subsequent pages of book Ch 4.]",
  "4.4": "ಅರ್ಜುನಃ ಉವಾಚ-ಅರ್ಜುನ ಕೇಳಿದನು:\n\nಅಪರಮ್‌ ಭವತಃ ಜನ್ಮ ಪರಮ್‌ ಜನ್ಮ ವಿವಸ್ವತಃ |\n\nಕಥಮ್‌ ಏತತ್‌ ವಿಜಾನೀಯಾಮ್‌ ತ್ವಮ್‌ ಆದೌ ಪ್ರೋಕ್ತವಾನ್‌ ಇತಿ-ನೀನು ಹುಟ್ಟಿದ್ದು ಇತ್ತೀಚೆಗೆ. ಸೂರ್ಯ\nಮೊದಲು ಹುಟ್ಟಿದವನು. ನೀನೇ ಮೊದಲು ಹೇಳಿದವನು ಎಂದರೆ ಇದನ್ನು ಹೇಗೆ ಅರ್ಥೈಸಲಿ?\n\nಜ್ಞಾನ ಪರಂಪರೆಯನ್ನು ವಿವರಿಸುವಾಗ ಕೃಷ್ಣ \"ನಾನು ಮೊದಲು ಸೂರ್ಯನಿಗೇದೇವತೆಗಳಿಗೆ) ಹೇಳಿದೆ”\nಎಂದಿದ್ದಾನೆ. ಇಲ್ಲಿ ಅರ್ಜುನ ಕೃಷ್ಣನನ್ನು ಈ ಕುರಿತು ಪ್ರಶ್ನಿಸುತ್ತಾನೆ. ವಯಸ್ಸಿನಲ್ಲಿ ಕೃಷ್ಣ ಅರ್ಜುನನಿಗಿಂತ\nಸುಮಾರು ಆರು ತಿಂಗಳು ದೊಡ್ಡವ. ಹಾಗಿರುವಾಗ ಕೋಟಿ-ಕೋಟಿ ವರ್ಷಗಳ ಹಿಂದೆ ಸೂರ್ಯನಿಗೆ ಹೇಳಿದೆ\nಅಂದರೆ ಇದನ್ನು ಹೇಗೆ ಅರ್ಥೈಸಲಿ ಎನ್ನುವುದು ಅರ್ಜುನನ ಪ್ರಶ್ನೆ.\n\nಇಲ್ಲಿ ಅರ್ಜುನನಿಗೆ ಸ್ವಯಂ ಭಗವಂತನಿಂದ ಈ ಪ್ರಶ್ನೆಗೆ ಉತ್ತರ ಪಡೆಯುವ ಆಸೆ. ಅದಕ್ಕಾಗಿ ಈ ಪ್ರಶ್ನೆಯನ್ನು\nಹಾಕಿದ್ದಾನೆ. ಇಷ್ಟೇ ಅಲ್ಲದೆ ಎಲ್ಲಾ ನರರ ಪ್ರತಿನಿಧಿಯಾಗಿ ನಿಂತ ಮಹಾಜ್ಞಾನಿ ಅರ್ಜುನ, ನಮ್ಮ ನಿಮ್ಮೆಲ್ಲರ ಪರ\nಈ ಪ್ರಶ್ನೆಯನ್ನು ಹಾಕುತ್ತಾನೆ. ಈ ಬಗ್ಗೆ ಪ್ರಾರಂಭದಲ್ಲೇ ಪ್ರಸ್ತಾಪಿಸಲಾಗಿದೆ. ಕೃಷ್ಣ ಹೇಳಿದ್ದ: \"ನಾವೆಲ್ಲರೂ\nಹಿಂದೆಯೂ ಇದ್ದೆವು, ಈಗ ಇದ್ದೇವೆ ಮತ್ತು ಮುಂದೆಯೂ ಇರುತ್ತೇವೆ\" ಎಂದು(ಅ-2 ,ಶ್ಲೋ-12. .. ಅದರ\nಸಂಪೂರ್ಣ ವಿವರಣೆ ಇಲ್ಲಿ ಬರುತ್ತದೆ. ಯಾವ ಕರ್ಮ ಬಂಧನವೂ ಇಲ್ಲದ, ಸರ್ವ ಸಮರ್ಥನಾದ ಭಗವಂತ\nಭೂಮಿಗೇಕೆ ಇಳಿದು ಬರುತ್ತಾನೆ ಎನ್ನುವ ಪ್ರಶ್ನೆಗೆ ಮುಂದಿನ ಶ್ಲೋಕಗಳಲ್ಲಿ ಕೃಷ್ಣ ಉತ್ತರಿಸಿದ್ದಾನೆ.",
  "4.5": "ಭಗವಾನ್‌ ಉವಾಚ-ಭಗವಂತ ಹೇಳಿದನು.\n\nಬಹೂನಿ ಮೇ ವ್ಯತೀತಾನಿ ಜನ್ಮಾನಿ ತವ ಚ ಅರ್ಜುನ |\n\nತಾನಿ ಅಹಮ್‌ ವೇದ ಸರ್ವಾಣಿ ನ ತ್ವಮ್‌ ವೇತ್ಥ ಪರಂತಪ-ಓ ಅರ್ಜುನಾ, ನನಗೆ ಹಲವಾರು ಹುಟ್ಟುಗಳು ಆಗಿ\nಹೋದವು. ನಿನಗೆ ಕೂಡಾ. ಓ ಅರಿಗಳನ್ನು ತರಿದವನೇ, ಅವೆಲ್ಲವನ್ನೂ ನಾನು ಬಲ್ಲೆ- ಆದರೆ ನಿನಗೆ ಗೊತ್ತಿಲ್ಲ.\n\nಜನ್ಮ ಅಂದರೆ ಜನನ ಅಥವಾ ಹುಟ್ಟುವುದು. ಇಲ್ಲದೇ ಇರುವುದು ಹುಟ್ಟು ವುದಿಲ್ಲ. ಜಡವನ್ನು ಹುಟ್ಟಿ ತು ಎಂದು\nನಾವು ಕರೆಯುವುದಿಲ್ಲ. ಸೂಕ್ಷ್ಮ ಶರೀರದಿಂದ ಸ್ಥೂಲ ಶರೀರದಲ್ಲಿ ಕಾಣಿಸಿಕೊಳ್ಳುವುದು ಜನನ. ಸಾಯುವುದು\nಅಂದರೆ ಸೂಕ್ಷ್ಮಶರೀರ ಸ್ಥೂಲಶರೀರವನ್ನು ತೈಜಿಸುವುದು. ಇಲ್ಲಿ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: \"ನನಗೆ ಹಾಗೂ ನಿನಗೆ\nಅನೇಕ ಹುಟ್ಟುಗಳು ಆಗಿ ಹೋದವು. ನನಗೆ ಅದು ತಿಳಿದಿದೆ ಆದರೆ ಪರಂತಪನಾದ ನಿನಗೂ ಈ ವಿಚಾರ\nತಿಳಿದಿಲ್ಲ\" ಎಂದು.",
  "4.6": "ಅಜಃ ಅಪಿ ಸನ್‌ ಅವ್ಯಯ ಆತ್ಮಾ ಭೂತಾನಾಮ್‌ ಈಶ್ವರಃ ಅಪಿ ಸನ್‌ |\n\nಪ್ರಕೃತಿಮ್‌ ಸ್ವಾಮ್‌ ಅಧಿಷ್ಠಾಯ ಸಂಭವಾಮಿ ಆತ್ಮಮಾಯಯಾ-ನನಗೆ ಹುಟ್ಟೆಂಬುದಿಲ್ಲ. ನನ್ನ ದೇಹಕ್ಕೆ ಕೂಡಾ\nಸಾವಿಲ್ಲ. ನಾನು ಎಲ್ಲಾ ಜೀವಿಗಳ ಒಡೆಯರಿಗೂ ಒಡೆಯ. ಆದರೂ ನನ್ನಂಕೆಯಲ್ಲಿರುವ ಪ್ರಕೃತಿಮಯವಾದ\nಶರೀರವನ್ನು ಹೊಕ್ಕು ಜ್ಞಾನ ಸ್ವರೂಪದಿಂದಲೇ (ನನ್ನ ಸಹಜ ಸ್ವಭಾವವನ್ನಾಧರಿಸಿ ನನ್ನಿಚ್ಛೆಯಿಂದಲೇ )\nಮೂಡಿಬರುವೆ.\n\nಸಮಸ್ತ ಜೀವಜಾತದ ಒಡೆಯನಾದ ಭಗವಂತ ಅನೇಕ ಬಾರಿ ಭೂಮಿಗೆ ಇಳಿದು ಬರುತ್ತಾನೆ. ಆತನಿಗೆ ಹುಟ್ಟು\nಅನ್ನುವುದಿಲ್ಲ. ಆದರೂ ಹುಟ್ಟಿ ಬರುತ್ತಾನೆ. ಆತ ಅವ್ಯಯ; ಆತ ನಶ್ವರವಾದ ದೇಹವನ್ನು ಹೊತ್ತು ಹುಟ್ಟು ವುದಿಲ್ಲ.\nಆದ್ದರಿಂದ ದೇಹದ ಮೂಲಕ ಹುಟ್ಟು-ಸಾವು ಭಗವಂತನಿಗಿಲ್ಲ. ಇಲ್ಲಿ ಬಂದಿರುವ 'ಆತ್ಮ ಮಾಯಯಾ' ಅನ್ನುವ\nಪದಕ್ಕೆ ಅನೇಕ ಅರ್ಥಗಳಿವೆ. ಜೀವಕ್ಕೆ ಕವಿದ ಮೋಹದ ಪರದೆ ಆತ್ಮ ಮಾಯೆ; ಭಗವಂತನ ಮಹಿಮೆ ಆತ್ಮ\nಮಾಯೆ; ಭಗವಂತನ ಸ್ವಂತ ಇಚ್ಚೆ ಹಾಗೂ ಜ್ಞಾನ ಆತ್ಮ ಮಾಯೆ. ಭಗವಂತ ಭೂಮಿಗೆ ಇಳಿದು ಬರುವುದು\nಆತನ ಜ್ಞಾನದ ಮಹಿಮೆಯಿಂದ ಹೊರತು ಯಾವುದೋ ಮಾಯೆಯ ಅಧೀನನಾಗಿ ಅಲ್ಲ. ಭಗವಂತ ತನ್ನ ಭಕ್ತರ\nಕಳಕಳಿಯನ್ನು ಈಡೇರಿಸುವುದಕ್ಕೋಸ್ಕರ ಇಚ್ಛಾಪೂರ್ವಕವಾಗಿ ತಾನೇ ನಿರ್ಮಿಸಿರುವ ಪ್ರಕೃತಿಯನ್ನು\nಮಾಧ್ಯಮವಾಗಿ ಬಳಸಿ ಇಳಿದು ಬರುತ್ತಾನೆ. ಇದು ಆತನ ಮಹಿಮೆ. ಮೋಹದ ಪರದೆಯಲ್ಲಿ ಬದುಕುವ ನಮಗೆ\nಇದು ಒಂದು ಸಾಮಾನ್ಯ ಹುಟ್ಟು ಎನ್ನುವಂತೆ ಕಾಣುತ್ತದೆ. ಏಕೆಂದರೆ ನಮಗೆ ಆತನ ಜ್ಞಾನಾನಂದಮಯ\nಶರೀರವನ್ನು ಕಾಣಲು ಸಾಧ್ಯವಿಲ್ಲ. ನಮಗೆ ಸ್ವಯಂ ನಮ್ಮ ಜೀವ ಸ್ವರೂಪದ ಅರಿವೇ ಇಲ್ಲ-ಹೀಗಿರುವಾಗ\nಭಗವಂತನನ್ನು ಅರಿಯುವುದು ಸಾಧ್ಯವೇ? ಈ ಕಾರಣದಿಂದ ನಮಗೆ ಭಗವಂತ ಪಾಂಚಭೌತಿಕ\nಶರೀರದವನಂತೆ ಕಾಣುತ್ತಾನೆ. ನಮಗೆ ತಿಳಿದಂತೆ ಕೆಲವು ಪ್ರಾಣಿಗಳಿಗೆ ಬಣ್ಣ ಕಾಣುವುದಿಲ್ಲ. ಅವುಗಳ ಕಣ್ಣಿಗೆ ಆ\nಶಕ್ತಿ ಇಲ್ಲ. ಆದ್ದರಿಂದ ಎಲ್ಲವೂ ಕಪ್ಪು ಬಿಳುಪು. ಆದರೆ ನಿಜವಾಗಿ ಪ್ರಪಂಚದಲ್ಲಿ ಬಣ್ಣವಿದೆ, ಆ ಪ್ರಾಣಿಗಳಿಗೆ\nಬಣ್ಣವನ್ನು ಗ್ರಹಿಸುವ ಶಕ್ತಿ ಇಲ್ಲ ಅಷ್ಟೇ. ಹಾಗೆಯೇ ಮೋಹದ ಪರದೆಯಲ್ಲಿ ಬದುಕುವ ನಮಗೆ ಭಗವಂತನ\nಜ್ಞಾನಾನಂದ ಸ್ವರೂಪ ಶರೀರ ಕಾಣಿಸುವುದಿಲ್ಲ, ಬದಲಿಗೆ ಪಾಂಚಭೌತಿಕ ಶರೀರ ಹುಟ್ಟಿ ನಾಶವಾದಂತೆ\nಕಾಣುತ್ತದೆ. ಆದರೆ ಮೂಲತಃ ಭಗವಂತನಿಗೆ ಹುಟ್ಟೂ ಇಲ್ಲ, ನಾಶವೂ ಇಲ್ಲ. ಆತ ತನ್ನ ಸಹಜ ಸ್ವಭಾವದಿಂದ\nಸ್ವ-ಇಚ್ಚೆಯಿಂದ ಮೂಡಿ ಬರುತ್ತಾನೆ.\n\nಭಗವಂತ ಯಾವ ಕಾರಣಕ್ಕೋಸ್ಕರ ಭೂಮಿಗಿಳಿದು ಬರುತ್ತಾನೆ? ಅದರ ಹಿಂದಿರುವ ದೈವೀ ಸಂಕಲ್ಪ ಏನು? ಈ\nಪ್ರಶ್ನೆಗೆ ಉತ್ತರವನ್ನು ಮುಂದಿನ ಎರಡು ಶ್ಲೋಕದಲ್ಲಿ ಕಾಣಬಹುದು.",
  "4.7": "ಯದಾಯದಾಹಿ ಧರ್ಮಸ್ಯ ಗ್ಲಾನಿಃ ಭವತಿ ಭಾರತ |\nಅಭ್ಯುತ್ಥಾನಮ್‌ ಅಧರ್ಮಸ್ಯ ತದಾ ಆತ್ಮಾನಮ್‌ ಸೃಜಾಮಿ ಅಹಮ್‌..ಓ ಭಾರತಾ, ಧರ್ಮ ಕಳೆಗುಂದಿದಾಗೆಲ್ದಾ,\nಅಧರ್ಮ ತಲೆಯತ್ತಿದಾಗೆಲ್ಲಾ ನಾನು ನನ್ನ ನ್ನು ಹುಟ್ಟಿ ಸಿಕೊಳ್ಳುತ್ತೇನೆ.\n\nಇಡಿಯ ಪ್ರಪಂಚದಲ್ಲಿ ಯಾವಾಗ ಧರ್ಮ ಮಲೀನವಾಗಿ ಅಧರ್ಮದ ಮುಂದೆ ಸೋಲೊಪ್ಪಿಕೊಂಡು, ತಲೆ\nಕೆಳಗಾಗಿ ನಿಲ್ಲುವ ಪ್ರಸಂಗ ಬರುತ್ತದೋ, ಆಗ ನಾನು ಧರೆಗಿಳಿದು ಬರುತ್ತೇನೆ ಎನ್ನು ತ್ತಾನೆ ಕೃಷ್ಣ. ಇಲ್ಲಿ ಧರ್ಮ\nಸೋಲುವುದು ಅಂದರೆ ಅದು ಒಂದು ಮನೆಗೆ- ಒಂದು ದೇಶಕ್ಕೆ ಸಂಬಂಧಪಟ್ಟ ವಿಚಾರವಲ್ಲ. ಇಡೀ ವಿಶ್ವದಲ್ಲೇ\n\nಧರ್ಮಕ್ಕೆ ನೆಲೆ ಸಿಗದ ಪರಿಸ್ಥಿತಿ ಬಂದಾಗ ಭಗವಂತನ ಅವತಾರವಾಗುತ್ತದೆ. ದುಷ್ಟ ಶಕ್ತಿಗಳು ಭೂಮಿಯ ಮೇಲೆ\nಹಿಡಿತ ಸಾಧಿಸಿ ಸತ್ವಗುಣದ ತಲೆ ಎತ್ತದಂತೆ ಮಾಡಿದಾಗ, ಭಗವಂತ ತನ್ನನ್ನು ತಾನು ಭೂಮಿಯ ಮೇಲೆ\nಸೃಷ್ಟಿಸಿಕೊಳ್ಳುತ್ತಾನೆ. \"ತದಾ55ತ್ಮಾನಂ ಸೃಜಾಮ್ಯಹಮ್‌\" ಎನ್ನುವಲ್ಲಿ 'ನಾನು ನನ್ನ ಆತ್ಮೀಯರನ್ನು\nಕಳುಹಿಸುತ್ತೇನೆ' ಎನ್ನುವ ಹಾಗೂ 'ನಾನೇ ಅವತರಿಸುತ್ತೇನೆ' ಎನ್ನುವ ಎರಡು ಧ್ವನಿ ಇದೆ. ಧರ್ಮಕ್ಕೆ\nಸೋಲಾಗುವ ಲಕ್ಷಣಗಳು ಪ್ರಾಂತೀಯವಾಗಿ ಕಂಡು ಬಂದಾಗ ಭಗವಂತ ತನಗೆ\nಆತ್ಮೀಯರಾದವರನ್ನು(ದೇವತೆಗಳನ್ನು) ಭೂಮಿಗೆ ಕಳುಹಿಸುತ್ತಾನೆ. ಅವರು ಆಚಾರ್ಯಪುರುಷರಾಗಿ ಬಂದು\nಸಮಾಜವನ್ನು ತಿದ್ದುತ್ತಾರೆ. ಇಂತಹ ವ್ಯವಸ್ಥೆ ಕೂಡಾ ಕುಸಿದು ತಾಮಸ ಶಕ್ತಿಗಳು ವಿಜೃಂಭಿಸಿದಾಗ,\nಕೊನೇಯದಾಗಿ ಭಗವಂತ ಸ್ವಯಂ ಅವತಾರವೆತ್ತುತ್ತಾನೆ. ಕೃಷ್ಣನ ಅವತಾರವಾದ ಸಮಯದ ಸ್ಥಿತಿಯನ್ನು\nಗಮನಿಸಿದಾಗ ಆ ಕಾಲದ ಧರ್ಮದ ಪಾಡೇನು ಎನ್ನುವುದು ಸ್ಪಷ್ಟವಾಗುತ್ತದೆ. ಜರಾಸಂಧ ಪ್ರಪಂಚದ ಮೂಲೆ\nಮೂಲೆಯಲ್ಲಿನ ಸುಮಾರು 22,800 ರಾಜಕುಮಾರರನ್ನು ತನ್ನ ಸೆರೆಯಲ್ಲಿಟ್ಟಿದ್ದ. ಕಂಸನಿಗೆ ತನ್ನ ಮಗಳನ್ನು\nಕೊಟ್ಟು ಆತನನ್ನು ಎತ್ತಿಕಟ್ಟಿ, ಶೂರಸೇನನನ್ನು ಸೆರೆಮನೆಗೆ ಹಾಕುವಂತೆ ಕುತಂತ್ರ ಮಾಡಿ, ಅದರಲ್ಲಿ\nಯಶಸ್ವಿಯಾಗಿದ್ದ ಜರಾಸಂಧ. ಇನ್ನು ಆತನ ಮಿತ್ರ ನರಕಾಸುರ ಸುಮಾರು 16,100 ರಾಜಕುಮಾರಿಯರನ್ನು\nಸೆರೆಮನೆಯಲ್ಲಿಟ್ಟಿದ್ದ. ಭೀಷ್ಮಾಚಾರ್ಯರೊಂದಿಗೆ ಶಾಂತಿ ಒಪ್ಪಂದ ಮಾಡಿಕೊಂಡು ಇಡೀ ಭೂಲೋಕದಲ್ಲಿ\nತನ್ನದೇ ಆದ ಏಕಚಕ್ರಾಧಿಪತ್ಯವನ್ನು ಸ್ಥಾಪಿಸುವ, ಹಾಗೂ ಜನರನ್ನು ಸುಲಿಗೆ ಮಾಡುವ ಕುತಂತ್ರ ರೂಪಿಸಿದ್ದ\nಜರಾಸಂಧ. ಅಂದಿನ ಭಾರತ ಇಂದಿನ ಭಾರತದಂತಿರಲಿಲ್ಲ. ಅದು ಅತಿದೊಡ್ಡ ಭೂ ಭಾಗವಾಗಿತ್ತು. ಒಂದು ವೇಳೆ\nಕೃಷ್ಣನ ಅವತಾರ ಆಗದೇ ಇದ್ದಿದ್ದರೆ ಇಡೀ ಭೂಲೋಕ ಈ ಪಾಪಿಗಳ ಕೈವಶವಾಗುತ್ತಿತ್ತು. ಇಂತಹ ಸಂದರ್ಭದಲ್ಲಿ\nಕೃಷ್ಣ ಅವತರಿಸಿದ. ಕಂಸನನ್ನು ಕೊಂದು ಶೂರಸೇನನನ್ನು ಮರಳಿ ರಾಜನನ್ನಾಗಿ ಮಾಡಿದ ಕೃಷ್ಣ,\nನರಕಾಸುರನನ್ನು ಕೊಂದು, ಆತನ ಕೈಕೆಳಗಿನ ರಾಜಕುಮಾರಿಯರನ್ನು ಬಿಡುಗಡೆಗೊಳಿಸಿದ. ಹೀಗೆ\nಬಿಡುಗಡೆಗೊಂಡ ರಾಜಕುಮಾರಿಯರು ಶೀಲ ಶಂಕಿಸುವ ಸಮಾಜಕ್ಕೆ ಹೆದರಿದಾಗ ಅವರಿಗೆ ಅಭಯವನ್ನು\nಕೊಟ್ಟು, ಅವರನ್ನು ತಾನೇ ಮದುವೆಯಾಗಿ ಅವರ ಗೌರವವನ್ನು ಕಾಪಾಡಿದ. ಜರಾಸಂಧ ಕೃಷ್ಣನ ಮೇಲೆ\nಸುಮಾರು 23 ಅಕ್ಷೋಹಿಣಿ ಸೈನ್ಯದೊಂದಿಗೆ ದಾಳಿ ಮಾಡಿದಾಗ ಓಡಿ ಹೋದಂತೆ ನಟಿಸಿ, ನಂತರ\nಭೀಮಾರ್ಜುನರೊಂದಿಗೆ ಜರಾಸಂಧನನ್ನು ಸಂಧಿಸಿ- ಅಲ್ಲಿ ನಡೆದ ಮಲ್ಲ ಯುದ್ಧದಲ್ಲಿ ಭೀಮನಿಂದ ಜರಾಸಂಧನ\nವಧೆಯಾಗುವಂತೆ ಮಾಡಿದ ಹಾಗೂ ಆತನ ಸೆರೆಯಲ್ಲಿದ್ದ ಎಲ್ಲಾ ರಾಜಕುಮಾರರನ್ನು ಅವರವರ ರಾಜ್ಯಕ್ಕೆ\nಕಳುಹಿಸಿಕೊಟ್ಟ.\n\nಹೀಗೆ ಇಡೀ ಭೂಲೋಕ ಅಧರ್ಮದ ದಾಸ್ಯಕ್ಕೆ ಗುರಿಯಾಗುವ ಸಂದರ್ಭ ಬಂದಾಗ ಮಾತ್ರ ಭಗವಂತನ\nಅವತಾರ ಭೂಲೋಕದಲ್ಲಿ ಆಗುತ್ತದೆ.\n",
  "4.8": "ಪರಿತ್ರಾಣಾಯ ಸಾಧೂನಾಮ್‌ ವಿನಾಶಾಯ ಚ ದುಷ್ಕೃತಾಮ್‌ |\nಧರ್ಮ ಸಂಸ್ಥಾಪನ ಅರ್ಥಾಯ ಸಂಭವಾಮಿ ಯುಗೇಯುಗೇ--ಸಜ್ಜನರನ್ನು ಉಳಿಸಲೆಂದು, ಕೇಡಿಗರನ್ನು\nಅಳಿಸಲೆಂದು, ಧರ್ಮವನ್ನು ನೆಲೆಗೊಳಿಸಲೆಂದು ಯುಗ ಯುಗದಲ್ಲೂ ಮೂಡಿಬರುತ್ತೇನೆ.\n\nಯಾರು ಸಮಾಜಕ್ಕೆ ಕೆಟ್ಟದ್ದನ್ನು, ಕೇಡನ್ನು ಮಾಡಿ ಅದರಿಂದ ಲಾಭ ಪಡೆದು ಮೆರೆಯುತ್ತಾರೋ, ಅಂಥವರ\nಪೂರ್ಣನಾಶಕ್ಕಾಗಿ, ಸಜ್ಜನರ ಮತ್ತು ಪ್ರಪಂಚದ ಸಮಗ್ರ ರಕ್ಷಣೆಗಾಗಿ, ಧರ್ಮದ ಬೀಜ ಬಿತ್ತಲು ಭಗವಂತ\nಭೂಲೋಕದಲ್ಲಿ ಅವತರಿಸುತ್ತಾನೆ. ಇಲ್ಲಿ ಯುಗೇ-ಯುಗೇ ಎಂದರೆ \"ಯುಗ-ಯುಗದಲ್ಲೂ' ಎಂದರ್ಥ. ಅಂದರೆ\nಭಗವಂತ ಪ್ರತೀ ಯುಗದಲ್ಲೂ ಅವತರಿಸುತ್ತಾನೆ ಎಂದರ್ಥವಲ್ಲ. ಆತ ಅವತರಿಸುವುದು ಮೇಲೆ ಹೇಳಿದ\nಸಂದರ್ಭ ಬಂದಾಗ ಮಾತ್ರ. ಒಂದೊಂದು ಯುಗದಲ್ಲಿ ಅನೇಕ ಅವತಾರವಿರಬಹುದು; ಇನ್ನು ಕೆಲವು ಯುಗದಲ್ಲಿ\nಅವತಾರವೇ ಇಲ್ಲದಿರಬಹುದು. ಆದರೆ ಭಗವಂತನ ಆವಿರ್ಭಾವವಿರುವ ಅನೇಕ ಮಹಾಪುರುಷರು ಯುಗ-\nಯುಗದಲ್ಲೂ ಬಂದು ಹೋಗುತ್ತಿರುತ್ತಾರೆ. ಅವರ ಮುಖೇನ ಭಗವಂತನ ಧರ್ಮ ರಕ್ಷಣೆ ಯುಗ ಯುಗದಲ್ಲೂ\nನಿರಂತರ.\n",
  "4.9": "ಜನ್ಮ ಕರ್ಮ ಚ ಮೇ ದಿವ್ಯಮ್‌ ಏವಮ್‌ ಯಃ ವೇತ್ತಿ ತತ್ವತಃ |\nತ್ಯಕ್ತ್ವಾ ದೇಹಮ್‌ ಪುನಃ ಜನ್ಮ ನ ಏತಿ ಮಾಮ್‌ ಏತಿ ಸಃ ಅರ್ಜುನ-ಹೀಗೆ ನನ್ನ ಅಲೌಕಿಕವಾದ ಹುಟ್ಟಿನ, ಕಜ್ವದ\nನಿಜವನ್ನರಿತವನು ದೇಹವನ್ನು ತೊರೆದು ಮರಳಿ ಹುಟ್ಟುವುದಿಲ್ಲ. ಅರ್ಜುನಾ-ಅವನು ನನ್ನನ್ನು ಸೇರುತ್ತಾನೆ.\n\nಹೀಗೆ. ಭಗವಂತನ ಜ್ಞಾನಾನಂದಮಯ, ದಿವ್ಯ(Divine), ಲೀಲಾಮಯ ಅವತಾರದ ಅರಿವು\nಯಥಾವತ್ತಾಗಿ(ತತ್ವತಃ) ಅರಿತರೆ, ಅದು ನಮಗೆ ಮೋಕ್ಷ ಮಾರ್ಗವನ್ನು ತೋರಬಲ್ಲದು. ಇದು ಮರು-ಹುಟ್ಟಿಲ್ಲದ\nಮೋಕ್ಷವನ್ನು ಪಡೆಯಲು ಬೇಕಾದ ಒಂದು ಅಮೂಲ್ಯ ಜ್ಞಾನ. ಈ ರೀತಿ ಅಧಿಷ್ಠಾನದಿಂದ ಸಿದ್ಧಿಯನ್ನು ಪಡೆದವರ\nಬಗ್ಗೆ ಕೃಷ್ಣ ಮುಂದೆ ವಿವರಿಸುತ್ತಾನೆ.\n",
  "4.10": "ವೀತ ರಾಗ ಭಯ ಕ್ರೋಧಾಃ ಮತ್‌ ಮಯಾ ಮಾಮ್‌ ಉಪಾಶ್ರಿತಾಃ |\n\nಬಹವಃ ಜ್ಞಾನ ತಪಸಾ ಪೂತಾಃ ಮತ್‌ ಭಾವಮ್‌ ಆಗತಾಃ -- ರಾಗ-ಭಯ-ಕ್ರೋಧವನ್ನು ತೊರೆದವರು,\nಎಲ್ಲೆಲ್ಲೂ ನನ್ನನ್ನೇ ಕಾಣುವವರು(ನನ್ನ ಹಿರಿಮೆಯನ್ನು ಅರಿತವರು), ನನಗೆ ಶರಣು ಬಂದವರು ಬಹಳ ಮಂದಿ-\nತಿಳಿವಿನ ತಪಸ್ಸಿನಿಂದ ತಿಳಿಗೊಂಡು ನನ್ನನ್ನು ಸೇರಿದ್ದಾರೆ.\n\nಮೂರನೇ ಅಧ್ಯಾಯದ ಕೊನೆಯಲ್ಲಿ(ಶ್ಲೋಕ-39) ಕೃಷ್ಣ ಹೇಳಿದಂತೆ ರಾಗ-ದ್ವೇಷಾದಿಗಳು ನಮ್ಮ ಪರಮ\nಶತ್ರುಗಳು. ನಾವು ನಮ್ಮ ಜೀವನದ ಸರ್ವ ಸಮಸ್ಯೆಗಳಿಗೆ ಕಾರಣವಾದ ಒಲವು(ಆಸೆ,ರಾಗ, Attachment,\nಅಂಜಿಕೆ (ಭಯ) ಮತ್ತು ಕೋಪ(ಸಿಟ್ಟು)ವನ್ನು ತೊರೆದು, ಏನು ಇದೆಯೋ ಅದರಲ್ಲಿ ಸಂತೋಷಪಡುವುದನ್ನು\nಮತ್ತು ಏನು ಬಂತೋ ಅದನ್ನು ಸಂತೋಷದಿಂದ ಸ್ವೀಕರಿಸುವ ಮನೋವೃತ್ತಿಯನ್ನು ಬೆಳೆಸಿಕೊಂಡು,\nಮನ್ಮಯರಾಗಬೇಕು. 'ಮನ್ಮಯ' ಅಂದರೆ ಜೀವನದ ಎಲ್ಲಾ ನಡೆಗಳಲ್ಲಿ ಭಗವಂತನನ್ನು ತುಂಬಿಸಿಕೊಳ್ಳುವುದು\nಮತ್ತು ಲೌಕಿಕ ಪ್ರಜ್ಞೆಯನ್ನು ಕಡಿಮೆ ಮಾಡಿಕೊಳ್ಳುವುದು. ಒಮ್ಮೆ ನಾವು ಭಗವಂತನ ಚಿಂತನೆಯಲ್ಲಿ ತೊಡಗಿದಾಗ\nಈ ರಾಗ-ದ್ವೇಷಗಳು ಕ್ಷುಲ್ಲಕವಾಗಿ ಕಾಣಲಾರಂಭಿಸುತ್ತವೆ. ಭಗವಂತ ಸರ್ವೋತ್ತಮ ಎನ್ನುವ ಸತ್ಯವನ್ನರಿತು,\nನಮ್ಮ ರಕ್ಷಣೆಗೆ ಸದಾ ಆತನಿದ್ದಾನೆ ಎಂದು ತಿಳಿದು, ದುರಾಭಿಮಾನವನ್ನು ಕಿತ್ತೆಸೆದು, ಆ ಭಗವಂತನಲ್ಲಿ\nಶರಣಾದವರು ಮೋಕ್ಷ ಮಾರ್ಗವನ್ನು ಕಾಣುತ್ತಾರೆ. ನಮ್ಮ ಜೀವನದ ಪ್ರತಿಯೊಂದು ಕರ್ಮದಲ್ಲಿ ಈ ರೀತಿಯ\nಭಾವನೆಯನ್ನು ಬೆಳೆಸಿಕೊಳ್ಳುವುದು ಒಂದು ತಪಸ್ಸು. ಇದರಿಂದ ನಮ್ಮ ಬದುಕು ಪವಿತ್ರವಾಗುತ್ತದೆ. ಹೀಗೆ ರಾಗ-\nದ್ವೇಷದ ಕೊಳೆಯಿಂದ ಮುಕ್ತರಾದವರು ನನ್ನನ್ನು ಸೇರುತ್ತಾರೆ ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ನಾವು ನಮ್ಮ ರಾಗ ದ್ವೇಷ-\nಕ್ರೋಧದಲ್ಲಿ ಕೂಡಾ ಭಗವಂತನನ್ನು ಕುಳ್ಳಿರಿಸಿಕೊಳ್ಳಬೇಕು! . ನಮ್ಮ ಆಸೆ-ಭಗವಂತನನ್ನು ಕಾಣುವ\nಆಸೆಯಾಗಿರಬೇಕು; ಭಯ-'ತಪ್ಪು ಮಾಡಿದರೆ ಭಗವಂತ ನನ್ನನ್ನು ಕ್ಷಮಿಸಲಾರ' ಎನ್ನುವ ಭಯವಾಗಿರಬೇಕು;\nನಮ್ಮ ಇಲ್ಲ ಸಲ್ಲದ ಇಂದ್ರಿಯಾಕಾಂಕ್ಷೆಗಳ ಮೇಲೆ ನಮ್ಮ ಕೋಪವಿರಬೇಕು. ಹೀಗೆ ಈ ಮೂರು ಶತ್ರುಗಳನ್ನು\nನಾವು ಭಗವಂತನ ಪರಗೊಳಿಸಿದಾಗ ಭಗವಂತನನ್ನು ಕಾಣಲು ಸಾಧ್ಯ.\n",
  "4.11": "ಯೇ ಯಥಾ ಮಾಮ್‌ ಪ್ರಪದ್ಯಂತೇ ತಾನ್‌ ತಥಾ ಏವ ಭಜಾಮಿ ಅಹಮ್‌ ।\n\nಮಮ ವರ್ತ್ಮಾ ಅನುವರ್ತಂತೇ ಮನುಷ್ಯಾಃ ಪಾರ್ಥ ಸರ್ವಶಃ -ಯಾರು ಹೇಗೆ ನನ್ನನು ಸೇವಿಸುತ್ತಾರೋ\nಅವರನ್ನು ಹಾಗೆಯೇ ನಾನು ಅನುಗ್ರಹಿಸುತ್ತೇನೆ. ಓ ಪಾರ್ಥಾ, ಮನುಷ್ಯರು ಯಾವ ದಾರಿಯಲ್ಲಿ ಸಾಗಿದರೂ\nಕೊನೆಗೆ ನನ್ನೆಡೆಗೆಯೇ ಬರುತ್ತಾರೆ.\n\nದೇವರ ಉಪಾಸನೆಗೆ ಸರಿಯಾದ ದಾರಿ ಯಾವುದು? ಒಬ್ಬಬ್ಬರು ಒಂದೊಂದು ರೀತಿ ಉಪಾಸನೆ ಮಾಡುತ್ತಾರೆ.\nಅದರಿಂದ ಗೊಂದಲ, ಆವೇಶ. ಯಾರು ಯಾವ ರೀತಿ ಉಪಾಸನೆ ಮಾಡುತ್ತಾರೋ ಭಗವಂತ ಹಾಗೆಯೇ\nಅನುಗ್ರಹಿಸುತ್ತಾನೆ. ನಾವು ಯಾವ ರೂಪದಿಂದ ಉಪಾಸನೆ ಮಾಡಿದರೂ ಅದು ವಿಶ್ವರೂಪನಾದ\nಭಗವಂತನನ್ನು ಸೇರುತ್ತದೆ. ಅದಕ್ಕಾಗಿ ನಾವು ನಮ್ಮ ಪೂಜೆಯನ್ನು ಭಗವಂತನ ವಿಶೇಷ ವಿಭೂತಿ ಇರುವ\nತುಳಸಿ, ಅಶ್ವತ್ಥವೃಕ್ಷ, ಗೋವು ಇತ್ಯಾದಿ ರೂಪದಲ್ಲಿ ಪೂಜಿಸುತ್ತೇವೆ. ಆದರೆ ಇಲ್ಲಿ ಒಂದು ಎಚ್ಚರ ಅಗತ್ಯ. ತುಳಸಿ\nಗಿಡವನ್ನೇ ಭಗವಂತನೆಂದು ನಂಬಿ ಪೂಜಿಸದೇ, ತುಳಸಿಯಲ್ಲಿ ಭಗವಂತನ ವಿಶೇಷ ವಿಭೂತಿ ಅಡಗಿದೆ ಎಂದು\n\nಪೂಜಿಸುವುದು ಮುಖ್ಯ. ಹೀಗೆ ನಮ್ಮ ಪ್ರತಿಯೊಂದು ಕ್ರಿಯೆಯಲ್ಲಿ ನಮಗೆ ಭಗವಂತನ ಎಚ್ಚರ ಮತ್ತು ಜ್ಞಾನ\nಅಗತ್ಯ. ಯಾವ ಹೆಸರಿನಿಂದ ಭಗವಂತನನ್ನು ಕರೆದರೂ ಅದು ಸರ್ವಶಬ್ದ ವಾಚ್ಯ ಭಗವಂತನ ನಾಮ ಎನ್ನುವ\nಎಚ್ಚರ ಅಗತ್ಯ. ಎಲ್ಲಿ ಕುಳಿತು ಪೂರ್ಣ ಅರ್ಪಣಾಭಾವದಿಂದ ಭಗವಂತನನ್ನು ನೆನೆದರೂ, ಅದು ವಿಶ್ವರೂಪಿ\nವಿಶ್ವಾಂಭರನನ್ನು ಸೇರುತ್ತದೆ. ಆತ ಸದಾ ನಮ್ಮ ರಕ್ಷಣೆ ಮಾಡುತ್ತಾನೆ.\n",
  "4.12": "ಕಾಂಕ್ಷಂತಃ ಕರ್ಮಣಾಮ್‌ ಸಿದ್ಧಿಮ್‌ ಯಜಂತೇ ಇಹ ದೇವತಾಃ |\nಕ್ಷಿಪ್ರಮ್‌ ಹಿ ಮಾನುಷೇ ಲೋಕೇ ಸಿದ್ಧಿಃ ಭವತಿ ಕರ್ಮಜಾ -ಕರ್ಮಗಳ ಮೂಲಕ ಫಲವನ್ನು ಬಯಸುವವರು ಇಲ್ಲಿ\nದೇವತೆಗಳನ್ನು ಪೂಜಿಸುತ್ತಾರೆ. ಈ ಭೂಮಿಯಲ್ಲಿ ಕರ್ಮದಿಂದ ಫಲ ಸಿದ್ಧಿ ಒಡನೆಯೇ ಕೈಗೂಡುತ್ತದೆಯಲ್ಲವೇ ?\n\nನಮ್ಮಲ್ಲಿ ಕೆಲವರು. ದೇವತೆಗಳಿಗೂ ಮತ್ತು ಭಗವಂತನಿಗೂ ವ್ಯತ್ಯಾಸ ತಿಳಿಯದೇ, ದೇವತಗಳನ್ನೇ\nಭಗವಂತನೆಂದು ಪೂಜಿಸುತ್ತಾರೆ. ಇದು ದೇವತೆಗಳ ಬಗ್ಗೆ ನಮ್ಮಲ್ಲಿರುವ ಒಂದು ತಪ್ಪು ಕಲ್ಪನೆ. ದೇವರು ಅನೇಕ\nಅಲ್ಲ ಆತ ಒಬ್ಬನೆ; ಆದರೆ ಭಗವಂತನ ಅಧೀನವಾಗಿರುವ ದೇವತೆಗಳು ಅನೇಕ. ನಾವು ತಕ್ಷಣ ಫಲ ಪಡೆಯುವ\nಅಪೇಕ್ಷೆಯಿಂದ ಭಗವಂತನನ್ನು ಮರೆತು. ದೇವತೆಗಳ ಸಮೂಹವನ್ನು ಪೂಜಿಸುವ ಸಂಪ್ರದಾಯವನ್ನು\nಬೆಳೆಸಿಕೊಂಡುಬಿಟ್ಟಿ ದ್ದೇವೆ. ಈ ರೀತಿ ಮಾಡುವುದರಿಂದ ಫಲ ಸಿಗಬಹುದು- ಆದರೆ ಅದು ಅಲ್ಪ ಕಾಲದ್ದು. ಐಹಿಕ\nಸುಖವನ್ನು ಬಯಸಿ ವಿವಿಧ ದೇವತೆಗಳನ್ನು ವಿವಿಧ ಫಲಕ್ಕಾಗಿ ಪೂಜಿಸುವುದು ನಮ್ಮನ್ನು ಶಾಶ್ವತವಾದ ಮೋಕ್ಷ\nಮಾರ್ಗದತ್ತ ಕೊಂಡೊಯ್ಯಲಾರದು. ಇಂದ್ರಿಯ ಭೋಗಕ್ಕಾಗಿ ಮಾಡುವ ಪೂಜೆ- ಪೂಜೆ ಎನಿಸಲಾರದು.\nದೇವತೆಗಳು ಮೋಕ್ಷ ಮಾರ್ಗದಲ್ಲಿ ನಮಗೆ ಸಹಾಯ ಮಾಡಬಲ್ಲರು, ಆದರೆ ಸರ್ವಶಕ್ತ ಭಗವಂತನ ಎಚ್ಚರ\nಬಹಳ ಮುಖ್ಯ.\n\nಭಗವಂತನನ್ನು ಯಾವ ರೂಪದಲ್ಲೇ ಪೂಜಿಸಿದರೂ ಐಹಿಕ ಭೋಗಕ್ಕಾಗಿ ಪೂಜಿಸದೇ, ಆ ಸರ್ವಾಂತರ್ಯಾಮಿ\nಭಗವಂತನನ್ನು ಸೇರುವ ಅನುಸಂಧಾನದಿಂದ ಪೂಜಿಸುವುದು ಅಧ್ಯಾತ್ಮ ಸಾಧನೆಯಲ್ಲಿ ಅತಿಮುಖ್ಯ ವಿಚಾರ.\nನೀನು ನಿನ್ನ ದೇವರನ್ನು ಕೃಷ್ಣ ಎಂದರೂ ಸರಿ, ಅಲ್ಲಾಹು ಎಂದರೂ ಸರಿ. ಆದರೆ ನಮ್ಮೆಲ್ಲರನ್ನೂ ಕಾಪಾಡಿ\nಪೋಷಿಸುವ ಶಕ್ತಿ ಒಂದೇ ಎನ್ನುವ ನಿಜ ತಿಳಿದಿರಲಿ. ಭಗವಂತನನ್ನು ವಿವಿಧ ರೂಪದಲ್ಲಿ ಪೂಜಿಸಬಹುದು. ಆದರೆ\nವಿವಿಧ ಭೋಗಕ್ಕಾಗಿ ವಿವಿಧ ದೇವತೆಗಳನ್ನು ದೇವರೆಂದು ಪೂಜಿಸುವುದು ಅಧ್ಯಾತ್ಮ ಸಾಧನೆಯಾಗಲಾರದು.\nದೇವತೆಗಳ ಮುಖೇನ ಅಥವಾ ದೇವತೆಗಳಲ್ಲಿ ಭಗವಂತನನ್ನು ಕಾಣುವುದು ತಪ್ಪಲ್ಲ. ಏಕೆಂದರೆ ಭಗವಂತ\nಸರ್ವಾಂತರ್ಯಾಮಿ, ಆತನಿರದ ಸ್ಥಳವಿಲ್ಲ. ಇದನ್ನು ಬಿಟ್ಟು ದೇವತೆಗಳನ್ನೇ ಭಗವಂತ ಎಂದು ಪೂಜಿಸಿದರೆ\nಅದನ್ನು ದೇವತೆಗಳೂ ಮೆಚ್ಚಲಾರರು.\n\nತನ್ನ ಅವತಾರದ ಉದ್ದೇಶ ಮತ್ತು ರಹಸ್ಯವನ್ನು ತಿಳಿಹೇಳಿದ ಕೃಷ್ಣ, ಅಂತಹ ಜ್ಞಾನದಿಂದ ಸಿದ್ಧಿ ಪಡೆದ\nಉದಾಹರಣೆ ನೀಡಿದ. ಬಹುದೇವತಾ ವಾದವನ್ನು ತೊಡೆದು ಹಾಕಿ ದೇವರು ಒಬ್ಬನೇ, ದೇವತೆಗಳು ಹಲವು\nಎನ್ನುವುದನ್ನು ಸ್ಪಷ್ಟಪಡಿಸಿದ ಹಾಗೂ ಉಪಾಸನೆ ಹೇಗಿರಬೇಕು ಎನ್ನುವುದನ್ನೂ ಸ್ಪಷ್ಟವಾಗಿ ಹೇಳಿದ. ಈ\nಸಂದರ್ಭದಲ್ಲಿ ನಮಗೆ ಒಂದು ಪ್ರಶ್ನೆ ಮೂಡಬಹುದು. ಮನುಕುಲದ ಸೃಷ್ಟಿ ಈ ಭೂಮಿಯ ಮೇಲೆ\nಭಗವಂತನಿಂದಾಯಿತು. ಆದರೆ ಒಬ್ಬ ಮಾನವ ಇನ್ನೊ ಬ್ಬನಂತಿಲ್ಲ. ಸ್ವಭಾವ ವೈವಿಧ್ಯತೆಯ ಮೂಲವೇನು?\nಭಗವಂತ ಒಬ್ಬಬ್ಬರನ್ನು ಒಂದೊಂದು ರೀತಿ ಏಕೆ ಸೃಷ್ಟಿ ಮಾಡಿದ್ದಾನೆ? ಈ ಪ್ರಶ್ನೆಗೆ ಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ಕೃಷ್ಣ\n\nಉತ್ತರಿಸುತ್ತಾನೆ.",
  "4.13": "ಚಾತುರ್ವರ್ಣ್ಯಮ್‌ ಮಯಾ ಸೃಷ್ಟಂ ಗುಣಕರ್ಮ ವಿಭಾಗಶಃ ।\n\nತಸ್ಯ ಕರ್ತಾರಮ್‌ ಅಪಿ ಮಾಮ್‌ ವಿದ್ಧಿ ಅಕರ್ತಾರಮ್‌ ಅವ್ಯಯಮ್‌ -- ತ್ರಿಗುಣಗಳು ಮತ್ತು ಕರ್ಮಗಳ\nವಿಂಗಡಣೆಯಿಂದ ನಾಲ್ಕು ವರ್ಣಗಳ ಗುಂಪನ್ನು ನಿರ್ಮಿಸಿದೆ. ಏತರಿಂದಲೂ ಬದಲಾವಣೆಗೊಳ್ಳದ ನಾನು\nಅದನ್ನು ಮಾಡಿದರೂ ನಿಜವಾಗಿ ಏನನ್ನೂ ಮಾಡುವುದಿಲ್ಲವೆಂದು ತಿಳಿ. (ಬದಲಾವಣೆಗೊಳ್ಳದ ನಾನು ಅದನ್ನು\nನಿರ್ಮಿಸಿದವನು ಮತ್ತು ನನ್ನನ್ನು ಯಾರೂ ನಿರ್ಮಿಸಿಲ್ಲ ಎಂದು ತಿಳಿ)\n\nಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: \"ನಾನು ಗುಣಕರ್ಮವಿಭಾಗಶಃ ನಾಲ್ಕು ವರ್ಣಗಳನ್ನು ಸೃಷ್ಟಿ ಮಾಡಿದೆ ಎಂದು”. ನಮಗೆ\nತಿಳಿದಂತೆ ನಾಲ್ಕು ವರ್ಣಗಳು- ಬ್ರಾಹ್ಮಣ, ಕ್ಷತ್ರಿಯ, ವೈಶ್ಯ ಮತ್ತು ಶೂದ್ರ. ಭಗವಂತನ ಈ ನುಡಿಯನ್ನು ತಪ್ಪಾಗಿ\nಅರ್ಥೈಸುವವರೇ ಹೆಚ್ಚು. ಭಗವಂತನೇ ನಾಲ್ಕು ವರ್ಣಗಳನ್ನು ಸೃಷ್ಟಿಸಿದರೆ ಈ ವರ್ಣಭೇದ ಭಾರತವನ್ನು ಬಿಟ್ಟು\nಬೇರೆ ದೇಶದಲ್ಲಿ ಏಕಿಲ್ಲ ಎಂದು ಪ್ರಶ್ನಿಸುವವರಿದ್ದಾರೆ. ಮೂಲಭೂತವಾಗಿ ನೋಡಿದರೆ ಕೃಷ್ಣ ಇಲ್ಲಿ ಹೇಳಿರುವುದು\nಜಾತಿಯ ಬಗ್ಗೆ ಅಲ್ಲ-ಬದಲಿಗೆ ನಾಲ್ಕು ವರ್ಣಗಳ ಬಗ್ಗೆ. ವರ್ಣ ಮತ್ತು ಜಾತಿಯನ್ನು ಸಂಕೀರ್ಣವಾಗಿ ಕೂಡಾ\nಬಳಸುತ್ತಾರೆ. ಸಂಸ್ಕೃತದಲ್ಲಿ ಒಂದು ಪದಕ್ಕೆ ಅನೇಕ ಅರ್ಥಗಳಿರುತ್ತವೆ. ಒಂದು ಪದಕ್ಕೆ ಅನೇಕ\nಆಯಾಮವಿರುವುದರಿಂದ ನಮಗೆ ಕೆಲವೊಮ್ಮೆ ಗೊಂದಲವಾಗುತ್ತದೆ. ಜಾತಿ ಎನ್ನುವುದಕ್ಕೆ ಎರಡು ಅರ್ಥವಿದೆ.\nಒಂದು ಹುಟ್ಟು ಗುಣ ಸ್ವಭಾವ(ಜೀವ ಸ್ವಭಾವ-ಹುಟ್ಟುವಾಗಲೇ ಪಡೆದುಕೊಂಡು ಬಂದಿದ್ದು, ಮೂಲ ತ್ರೈಗುಣ್ಯಕ್ಕೆ\nಸಂಬಂಧಪಟ್ಟ ದ್ದು) ಅದು ವರ್ಣ; ಇನ್ನೊಂದು ಯಾವ ಮನೆಯಲ್ಲಿ ಹುಟ್ಟಿ ದನೋ ಆ ಜಾತಿ (ಬ್ರಾಹ್ಮಣರ ಮನೆಯಲ್ಲಿ\nಹುಟ್ಟಿದ ಹುಡುಗ ಬ್ರಾಹ್ಮಣ ಹುಡುಗ, ಕ್ಷತ್ರಿಯನ ಮನೆಯಲ್ಲಿ ಹುಟ್ಟಿದ ಹುಡುಗ ಕ್ಷತ್ರಿಯ ಹುಡುಗ). ಈ ಸೂಕ್ಷ್ಮ\nಅರಿಯದಿದ್ದರೆ ಇಲ್ಲಿ ನಮಗೆ ಗೊಂದಲವಾಗುತ್ತದೆ. ಆದ್ದರಿಂದ ಈ ಶ್ಲೋಕದಲ್ಲಿ ವರ್ಣ ಎಂದರೆ ಮೂಲ ಹುಟ್ಟು\nವರ್ಣ ಅಂದರೆ ಬಣ್ಣ. ಒಬ್ಬ ಮನುಷ್ಯನ ಬಣ್ಣ ಅಂದರೆ ಏನು ? \"ಆತನ ಬಣ್ಣ ಬಯಲಾಯಿತು\" ಎಂದು\nಸಾಮಾನ್ಯವಾಗಿ ನಾವು ಹೇಳುವುದಿದೆ. ಒಬ್ಬನ ಬಣ್ಣ ಬಯಲಾಗುವುದು ಎಂದರೆ ಆತನ ನಿಜ ವ್ಯಕ್ತಿತ್ವ\n\nಬಯಲಾಗುವುದು. ಇಲ್ಲಿ ಬಣ್ಣ ಎಂದು ಹೇಳಲು ಇನ್ನೊಂದು ಕಾರಣವಿದೆ. ನಮ್ಮ ಸ್ವಭಾವಕ್ಕೆ ಬಣ್ಣವಿದೆ [ಇದು\nನಮ್ಮ ಕಣ್ಣಿಗೆ ಕಾಣದ ಬಣ್ಣ]. ಸಾತ್ವಿಕ-ಬಿಳಿ; ರಾಜಸ-ಕೆಂಪು; ತಾಮಸ-ಕಪ್ಪು. ಹೀಗೆ ಬಣ್ಣ ಸ್ವಭಾವವನ್ನು\nಪ್ರತಿನಿಧಿಸುತ್ತದೆ. ಅಷ್ಟೇ ಅಲ್ಲದೇ ನಮ್ಮ ಸ್ವಭಾವ ನಮ್ಮೊಳಗಿನ ಒಂದು ಶಕ್ತಿ. ನಮ್ಮ ಭಾವನೆಗನುಗುಣವಾಗಿ\nನಮ್ಮ ದೇಹ ಬಣ್ಣದ ಕಿರಣಗಳನ್ನು ಹೊರಹೊಮ್ಮುತ್ತದೆ[(ಇದು ಸಾಮಾನ್ಯ ಮನುಷ್ಯನ ಕಣ್ಣಿಗೆ ಕಾಣದು]. ತುಂಬಾ\nಕೋಪ ಬಂದಾಗ ಮೈಯಿಂದ ಕೆಂಪು ಕಿರಣ; ಮನಸ್ಸು ಪ್ರಸನ್ನವಾಗಿದ್ದಾಗ ಹಸಿರು ಕಿರಣ; ಜ್ಞಾನದ ಆಳ ತಿಳಿದ\nಜ್ಞಾನಿಯ ಮೈಯಿಂದ ನೀಲ ಕಿರಣ. ಹೀಗೆ ಬಣ್ಣ ನಮ್ಮ ಒಳಗಿನ ಸ್ವಭಾವವನ್ನು ಪ್ರತಿನಿಧಿಸುತ್ತದೆ. ಈ\nಕಾರಣಕ್ಕಾಗಿ ಜ್ಞಾನಾನಂದಮಯನಾದ ಭಗವಂತ ನೀಲಮೇಘಶ್ಯಾಮ.\nಮೇಲಿನ ವಿವರವನ್ನು ತಿಳಿದಾಗ ಸ್ಪಷ್ಟವಾಗಿ ನಮಗೆ ಅರ್ಥವಾಗುವುದು ಒಂದು ವಿಚಾರ. ಜಾತಿ ಹುಟ್ಟಿದ ಮನೆಗೆ\nಮತ್ತು ತಂದೆ-ತಾಯಿಯನ್ನು ಅವಲಂಬಿಸಿ ಬರುವುದು. ವರ್ಣ ಎನ್ನುವುದು ನಮ್ಮ ಅಂತರಂಗ ಪ್ರಪಂಚ-ನಮ್ಮ\nಮೂಲ ಸ್ವಭಾವ. ಈ ವರ್ಣವನ್ನು ಪ್ರಪಂಚದ ಮೂಲೆ ಮೂಲೆಯಲ್ಲೂ ಕಾಣಬಹುದು. ಭಾರತದಲ್ಲಿ ಶಾಸ್ತ್ರಕಾರರು\nಇದನ್ನು ಗುರುತಿಸಿ ಅದಕ್ಕೆ ಬ್ರಾಹ್ಮಣ, ಕ್ಷತ್ರಿಯ, ವೈಶ್ಯ ಮತ್ತು ಶೂದ್ರ ಎನ್ನುವ ಹೆಸರು ಕೊಟ್ಟರು ಅಷ್ಟೇ. ಜಾತಿ\nಜನ್ಮತಃ ಆದರೆ ವರ್ಣಗಳನ್ನು ಗುಣಕರ್ಮದಿಂದ ವಿಭಾಗಿಸಿರುವುದು. ಬ್ರಾಹ್ಮಣರ ಮನೆಯಲ್ಲಿ ಹುಟ್ಟುವ ಹುಡುಗ\nಬ್ರಾಹ್ಮಣ ಜಾತಿಯ ಹುಡುಗ. ಆದರೆ ಆತ ಸ್ವಭಾವತಃ ಕ್ಷತ್ರಿಯನಾಗಿರಲೂಬಹುದು; ಒಂದೇ ಮನೆಯಲ್ಲಿ ನಾಲ್ಕು\nವರ್ಣದ ಮಕ್ಕಳು ಹುಟ್ಟಲೂಬಹುದು. ಬೆಸ್ತರ ಹುಡುಗಿಯಲ್ಲಿ ಹುಟ್ಟಿದ ವೇದವ್ಯಾಸರು ಮಹಾಬ್ರಾಹ್ಮಣ. ಇದು\nವರ್ಣವನ್ನು ಅವಲಂಬಿಸಿ ಬಂದದ್ದು. ಅದೇ ವೇದವ್ಯಾಸರ ಮಗ, ಶ್ರೇಷ್ಠ ಜ್ಞಾನಿ-ವಿದುರ 'ಕ್ಷತ್ತಾಕೆಲಸದವಳ\nಮಗ). ಇದು ಸಾಮಾಜಿಕ ರಾಜಕೀಯದಿಂದ ಬಂದಿದ್ದು! ಜೀವಸ್ವಭಾವ ಮತ್ತು ಕರ್ಮಕ್ಕನುಗುಣವಾಗಿ ಭಗವಂತ\nಒಂದು ವರ್ಣವನ್ನು ಜೀವಕ್ಕೆ ಹುಟ್ಟುವಾಗಲೇ ಕೊಟ್ಟಿರುತ್ತಾನೆ.\nವರ್ಣ ಇಲ್ಲದೆ ಸಮಾಜ ಸುಗಮವಾಗಿ ನಡೆಯದು. ಪುರುಷಸೂಕ್ತದಲ್ಲಿ ಈ ನಾಲ್ಕು ವರ್ಣಗಳನ್ನು ಆಯಾ ವರ್ಣದ\nಕರ್ಮಕ್ಕನುಗುಣವಾಗಿ ದೇಹದ ನಾಲ್ಕು ಭಾಗವಾಗಿ ಈ ರೀತಿ ವಿವರಿಸಿದ್ದಾರೆ:\n\nಬ್ರಾಹ್ಮಣೋಸ್ಯ ಮುಖಮಾಸೀತ್‌ | ಬಾಹೂ ರಾಜನ್ಯಃ ಕೃತಃ |\n\nಊರೂ ತದಸ್ಯ ಯದ್ವೈಶ್ಯಃ | ಪದ್ಭ್ಯಾಗಮ್‌ ಶೂದ್ರೋ ಅಜಾಯತ ॥\nದೇಹಕ್ಕೆ ಪಂಚಾಗವಾಗಿರುವ ಹಾಗೂ ಪೂಜೆಯಲ್ಲಿ ಶ್ರೇಷ್ಠ ಎನಿಸಿದ ಪಾದವನ್ನು ಶೂದ್ರನಿಗೆ ಹೋಲಿಸಿದರು. ಇದು\nದೇಹದ ಅಡಿಪಾಯ. ಶೂದ್ರ ಎಂದರೆ ದುಃಖದಲ್ಲಿ ಕರಗಿದವ ಎಂದರ್ಥ. ಈತನಲ್ಲಿ ಅರಸೊತ್ತಿಗೆ ಇರುವುದಿಲ್ಲ.\nಆದರೆ ಇನ್ನೊಬ್ಬರ ಸೇವೆ ಮಾಡುವ ಸೇವಾ ಗುಣ ಮಹತ್ವವಾಗಿರುತ್ತದೆ. ಈ ಗುಣ ಇಲ್ಲದವ\nಮನುಷ್ಯನೇ ಅಲ್ಲ. ಯಾರೂ ಏಕವರ್ಣದವರಲ್ಲ. ಎಲ್ಲರಲ್ಲೂ ಎಲ್ಲಾ ಸ್ವಭಾವವಿರುತ್ತದೆ. ಯಾವ ಸ್ವಭಾವ ನಮ್ಮಲ್ಲಿ\nಹೆಚ್ಚಾಗಿದೆಯೋ ನಾವು ಆ ವರ್ಣಕ್ಕೆ ಸೇರುತ್ತೇವೆ. ಶೂದ್ರ ಸ್ವಭಾವ ಎಷ್ಟು ಮುಖ್ಯ ಎಂದರೆ ಈ\nಸ್ವಭಾವ ಇಲ್ಲದೆ ಬೇರೆ ಸ್ವಭಾವಕ್ಕೆ ಬೆಲೆಯೇ ಇಲ್ಲ. ಯಾವಾಗಲೂ ನಾವು. ಮಾಡುವ ಕರ್ಮವನ್ನು ಸೇವಾ\nಮನೋವೃತ್ತಿಯಿಂದ ಮಾಡಬೇಕು. ಉದಾಹರಣೆಗೆ: ಬ್ರಾಹ್ಮಣನಾದವನು ಸಮಾಜ ಸೇವೆಯ ಭಾವನೆಯಿಂದ\nಜ್ಞಾನದಾನ ಮಾಡಬೇಕು. ಇಲ್ಲದಿದ್ದರೆ ಅದು ಜ್ಞಾನದಾನವೆನಿಸುವುದಿಲ್ಲ.\nವೈಶ್ಯನನ್ನು.. ದೇಹದ ಸೊಂಟದ ಭಾಗಕ್ಕೆ ಹೋಲಿಸಿದರು. ಕಾರಣ ಈತನ ಸ್ವಭಾವ ವ್ಯಾಪಾರ ಮತ್ತು\nವಾಣಿಜ್ಯ. ಸಾಮಾನ್ಯವಾಗಿ ಹಿಂದಿನ ಕಾಲದ ಜೀವನ ಪದ್ಧತಿಯಂತೆ ವೈಶ್ಯರು ಒಂದು\n\nಊರಿನಿಂದ ಇನ್ನೊಂದು ಊರಿಗೆ ಸಂಚರಿಸುತ್ತಾ ತಮ್ಮ ವ್ಯಾಪಾರವನ್ನು ಮಾಡುತ್ತಿದ್ದರು. ಆದ್ದರಿಂದ ಅವರನ್ನು\nಸೊಂಟಕ್ಕೆ ಹೋಲಿಸಿದ್ದಾರೆ.\n\nಕ್ಷತ್ರಿಯರ ಸ್ವಭಾವ ತಮ್ಮ ತೋಳ್ಪಲದಿಂದ ಸಮಾಜದ ರಕ್ಷಣೆ ಮಾಡುವುದು ಮತ್ತು ಆಡಳಿತ ನೆಡೆಸುವುದಾದ್ದರಿಂದ ಅವರನ್ನು ತೋಳಿಗೆ ಹೋಲಿಸಿದ್ದಾರೆ.\n\nಇನ್ನು ಬ್ರಾಹ್ಮಣ ಸ್ವಭಾವ; ಇವರ ಮೂಲಕರ್ಮ ಜ್ಞಾನದ ಮಾರ್ಗದರ್ಶನ. ಅದಕ್ಕಾಗಿ ಇವರನ್ನು\nತಲೆಗೆ ಹೋಲಿಸಿದರು. ಸ್ವಭಾವತಃ ಬ್ರಾಹ್ಮಣ ಎನಿಸಿದವನು ಸದಾ ಭಗವಂತನ ಚಿಂತನೆ, ಇಂದ್ರಿಯ ನಿಗ್ರಹ,\nಸುಳ್ಳು ಹೇಳದ, ಮುಖವಾಡ ಇಲ್ಲದ ಬದುಕು, ಸದಾ ಅಂತರಂಗ ಬಹಿರಂಗ ಶುದ್ಧಿ- ಈ ಮೂಲ ಗುಣಗಳನ್ನು\nಹೊಂದಿರುತ್ತಾನೆ.\n\nಹೀಗೆ ಈ ನಾಲ್ಕು ವರ್ಣಗಳು ಸೇರಿದರೆ ಮಾತ್ರ ಒಂದು ಪರಿಪೂರ್ಣ ಸಮಾಜ ನಿರ್ಮಾಣವಾಗಲು ಸಾಧ್ಯ. ಇಲ್ಲಿ\nಮೇಲು-ಕೀಳು ಎನ್ನು ವ ಭಾವನೆ ಸಲ್ಲದು. ಎಲ್ಲರೂ ಮೋಕ್ಷ ಯೋಗ್ಯ ಜೀವರೇ. ಇದು ಆಧ್ಯಾತ್ಮಿಕ ವರ್ಗೀಕರಣ\nಮತ್ತು ವ್ಯವಸ್ಥೆ. 'ಇದನ್ನು ಅನಾದಿನಿತ್ಯವಾದ ಜೀವದ ಮೂಲ ಸ್ವಭಾವಕ್ಕನುಗುಣವಾಗಿ ಮತ್ತು\nಕರ್ಮಕ್ಕನುಗುಣವಾಗಿ ನಾನು ಈ ಭೂಮಿ ಮೇಲೆ ಸೃಷ್ಟಿಸಿದೆ' ಎಂದಿದ್ದಾನೆ ಕೃಷ್ಣ.\n\nಇಲ್ಲಿ ನಾವು ತಿಳಿಯಬೇಕಾದ ಒಂದು ಮೂಲಭೂತ ಅಂಶವೇನೆಂದರೆ- ಜೀವವನ್ನು ಭಗವಂತ ಸೃಷ್ಟಿ ಪಿಲ್ಲ. ಜೀವ\nಮತ್ತು ಜೀವಸ್ವಭಾವ ಅನಾದಿನಿತ್ಯ. ಜೀವದ ಸ್ವಭಾವಕ್ಕನುಗುಣವಾಗಿ ಅದಕ್ಕೆ ಬೇಕಾದ ದೇಹ, ಶಕ್ತಿ, ಪ್ರಪಂಚದ\nನಿರ್ಮಾಣ ಮಾಡಿ, ಅದಕ್ಕೊಂದು ಅಸ್ತಿತ್ವ. ಕೊಟ್ಟು, ಜೀವಸ್ವಭಾವದ ವಿಕಾಸಕ್ಕೋಸ್ಕರ ಜೀವವನ್ನು ಬಿತ್ತಿ\nಬೆಳೆಸುವವ ಭಗವಂತ. ಇಂತಹ ಭಗವಂತ ಎಲ್ಲರ ಕರ್ತಾರ. ಇಂತಹ ಭಗವಂತನಿಗೆ ಇನ್ನೊಬ್ಬ ಕರ್ತಾರನಿಲ್ಲ.\nಆತ ಎಲ್ಲವುದರ ಕಾರಣ ಆದರೆ ಆತನಿಗೆ ಕಾರಣವಾದ ಇನ್ನೊಂದು ವಸ್ತು ಇಲ್ಲ. \"ಬದಲಾವಣೆಗೊಳ್ಳದ ನಾನು\nಅದನ್ನು ನಿರ್ಮಿಸಿದವನು ಮತ್ತು ನನ್ನನ್ನು ಯಾರೂ ನಿರ್ಮಿಸಿಲ್ಲ ಎಂದು ತಿಳಿ” ಎಂದು ಕೃಷ್ಣ ಅರ್ಜುನನಿಗೆ\nಹೇಳುತ್ತಾನೆ.\n",
  "4.14": "ನ ಮಾಂ ಕರ್ಮಾಣಿ ಲಿಂಪಂತಿ ನಮೇ ಕರ್ಮಫಲೇ ಸ್ಚೃಹಾ\nಇತಿ ಮಾಮ್‌ ಯಃ ಅಭಿಜಾನಾತಿ ಕರ್ಮಭಿಃ ನ ಸಃ ಬಧ್ಯತೇ-ಕರ್ಮಗಳು ನನ್ನ ನ್ನು ಅಂಟುವುದಿಲ್ಲ. ನನಗೆ\nಕರ್ಮಫಲದ ಬಯಕೆಯಿಲ್ಲ. ಹೀಗೆಂದು ನನ್ನ ನ್ನು ತಿಳಿದವನು ಕರ್ಮದ ಸೆರೆಯಲ್ಲಿ ಸಿಕ್ಕಿ ಬೀಳನು.\n\nಭಗವಂತ ಅವರವರ ಸ್ವಭಾವಕ್ಕೆ ತಕ್ಕಂತೆ, ಅವರವರ ಕರ್ಮಕ್ಕೆ ತಕ್ಕಂತೆ (ಗುಣಕರ್ಮ ವಿಭಾಗಶಃ)\nಪ್ರಪಂಚವೆಂಬ ತೋಟವನ್ನು ನಿರ್ಮಿಸಿ, ನಾಲ್ಕು ವರ್ಣದ ಮೋಕ್ಷಯೋಗ್ಯ ಮಾನವರ ಸೃಷ್ಟಿಯನ್ನು ಈ ಭೂಮಿ\nಮೇಲೆ ಮಾಡಿದ. \"ಇದರಿಂದ ನನಗೆ ಯಾವ ಕರ್ಮವೂ ಅಂಟುವುದಿಲ್ಲ” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಕರ್ಮ ಅಂಟುವುದು\n'ಇದು ನನ್ನದು', 'ನಾನು ಮಾಡಿದ್ದು' ಎನ್ನುವ ಅಭಿಮಾನವಿದ್ದಾಗ ಮಾತ್ರ. ಭಗವಂತನಿಗೆ ಕರ್ಮದ ಅಂಟು\n\nಅಥವಾ ನಂಟು ಇಲ್ಲ. ಕರ್ಮಫಲದ ಅಭಿಮಾನವಿಲ್ಲ. ಆತನಿಗೆ ಕರ್ಮದ ಪರಿಶ್ರಮ, ಆಯಾಸಪೂರ್ವಕ ಕರ್ತೃ ಲ್ಲ\nಫಲದ ಬಯಕೆ ಇಲ್ಲ. ಈ ಸತ್ಯವನ್ನು ಅರಿತವ, ಅರಿತು ಅದನ್ನು ತನ್ನ ಜೀವನದಲ್ಲಿ ಅಳವಡಿಸಿಕೊಂಡವ, ಕರ್ಮ\nಬಂಧನದಲ್ಲಿ ಸಿಕ್ಕಿಬೀಳನು.\n",
  "4.15": "ಏವಮ್‌ ಜ್ಞಾತ್ವಾ ಕೃತಮ್‌ ಕರ್ಮ ಪೂರ್ವೈಃ ಅಪಿ ಮುಮುಕ್ಷುಭಿಃ\n\nಕುರು ಕರ್ಮ ಏವ ತಸ್ಮಾತ್‌ ತ್ವಮ್‌ ಪೂರ್ವೈಃ ಪೂರ್ವ ತರಮ್‌ ಕೃತಮ್‌-ಬಿಡುಗಡೆ ಬಯಸಿದ ಹಿಂದಿನವರು\nಕೂಡಾ ಹೀಗೆ “ತಿಳಿದು' ಕರ್ಮ ಮಾಡಿದರು. ಆದ್ದರಿಂದ ಹಿಂದಿನಿಂದಲೂ ಇದ್ದು ಹಿರಿಯರು ಮಾಡಿಕೊಂಡು ಬಂದ\nಕರ್ಮವನ್ನೇ ನೀನು ಮಾಡು .\n\nಕರ್ಮದ ಬಂಧನದಿಂದ ಬಿಡಿಸಿಕೊಳ್ಳಲು \"ನಿಷ್ಕ್ರೀಯತೆ' ಸುಲಭೋಪಾಯ ಎಂದು ಕೆಲವರು ಯೋಚಿಸಬಹುದು.\nಕೃಷ್ಣ ನಿಷ್ಕ್ರೀಯತೆಯನ್ನು ಉಗ್ರವಾಗಿ ವಿರೋಧಿಸುತ್ತಾನೆ. 'ನೂರು ವರುಷ ಬದುಕು ಆದರೆ ಕರ್ತವ್ಯಕರ್ಮ\nಮಾಡಿಕೊಂಡು ಬದುಕು. ನಿಷ್ಕ್ರಿಯನಾಗಿ ಬದುಕಬೇಡ'. ಇದು ಕೃಷ್ಣನ ಸಿದ್ಧಾಂತ. ಕರ್ಮ ಮಾಡುವುದು ಎಂದರೆ\nಏನನ್ನಾದರೂ ಮಾಡುವುದಲ್ಲ. ನಮ್ಮ ಜೀವಸ್ವಭಾವ(ವರ್ಣ)ಕ್ಕೆ ತಕ್ಕಂತೆ ಕರ್ಮ ನಡೆಯುತ್ತಿರಬೇಕು. ಮಾಡುವ\nಕರ್ಮವನ್ನು ಜ್ಞಾನಪೂರ್ವಕವಾಗಿ ತಿಳಿದು ಅಭಿಮಾನ-ಅಹಂಕಾರ-ಫಲಾಪೇಕ್ಷೆ ಇಲ್ಲದೇ ಮಾಡಬೇಕು. \"ನಿನ್ನ\nಹಿಂದಿನ ರಾಜರ್ಷಿಗಳು, ಋಷಿ-ಮುನಿಗಳು ಮಾಡಿದ್ದೂ ಇದನ್ನೇ . ಕರ್ಮಯೋಗ ಮತ್ತು ಜ್ಞಾನಯೋಗವೆಂಬ\nಉಭಯ ಯೋಗವಿಲ್ಲದೇ ಭಗವಂತನ ಸಂಯೋಗವಿಲ್ಲ” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.",
  "4.16": "ಕಿಮ್‌ ಕರ್ಮ ಕಿಮ್‌ ಅಕರ್ಮ ಇತಿ ಕವಯಃ ಅಪಿ ಅತ್ರ ಮೋಹಿತಾಃ\n\nತತ್‌ ತೇ ಕರ್ಮ ಪ್ರವಕ್ಷ್ಯಾಮಿ ಯತ್‌ ಜ್ಞಾತ್ವಾ ಮೋಕ್ಷ್ಯಸೇ ಅಶುಭಾತ್‌-ಯಾವುದು ಕರ್ಮ, ಯಾವುದು ಅಕರ್ಮ\nಎಂಬಲ್ಲಿ ಬಲ್ಲವರು ಗಲಿಬಿಲಿಗೊಳ್ಳುತ್ತಾರೆ. ಅಂತಹ ಕರ್ಮವನ್ನು ನಿನಗೆ ತಿಳಿಹೇಳುತ್ತೇನೆ. ಅದನ್ನು ಅರಿತು ನೀನು\nಕೇಡಿನಿಂದ ಪಾರಾಗುವೆ.",
  "4.17": "ಕರ್ಮಣಃ ಹಿ ಅಪಿ ಬೋದ್ಧವ್ಯಮ್‌ ಬೋದ್ಧವ್ಯಮ್‌ ಚ ವಿಕರ್ಮಣಃ।\n\nಅಕರ್ಮಣಃ ಚ ಬೋದ್ಧವ್ಯಮ್‌ ಗಹನಾ ಕರ್ಮಣಃ ಗತಿಃ -- ಕರ್ಮದ ಬಗ್ಗೆಯೂ ತಿಳಿಯಬೇಕು. ವಿರುದ್ಧ ಕರ್ಮದ\nಬಗೆಗೂ ತಿಳಿಯಬೇಕು, ಕರ್ಮ ತ್ಯಾಗದ ಬಗೆಗೂ ತಿಳಿಯಬೇಕು.[ಕರ್ಮವನ್ನು ನಮ್ಮಿಂದ ತಿಳಿಯಬೇಕು.\nವಿಕರ್ಮವನ್ನು ನಮ್ಮಿಂದ ತಿಳಿಯಬೇಕು; ಆಕರ್ಮವನ್ನೂ ನಮ್ಮಿಂದ ತಿಳಿಯಬೇಕು.] ಕರ್ಮದ ನಡೆ\nನಿಗೂಢವಾದದ್ದು.\n\nಯಾವುದು ಕರ್ಮ, ಯಾವುದು ಅಕರ್ಮ ಎನ್ನುವುದು ಜ್ಞಾನಿಗಳಿಗೂ ಕೂಡಾ ಗೊಂದಲದ ವಿಷಯ. ನಾವು\nಮಾಡುವುದನ್ನು ತಿಳಿದು ಮಾಡಬೇಕು. ನಮ್ಮ ಕರ್ಮ ಜ್ಞಾನಪೂರ್ವಕವಾಗಿರಬೇಕು. ಆದ್ದರಿಂದ ಕರ್ಮ ಎಂದರೆ\nಏನು ಎನ್ನುವುದನ್ನು ಮೊದಲು ನಿನಗೆ ಹೇಳುತ್ತೇನೆ. ಇದರಿಂದ ನೀನು ಕೇಡಿನಿಂದ ಪಾರಾಗುವೆ ಎನ್ನುತ್ತಾನೆ.\nಕೃಷ್ಣ.\n\nಕರ್ಮದ ಬಗ್ಗೆ ತಿಳಿಯುವುದು ಅಷ್ಟು ಸುಲಭವಲ್ಲ. ಆದರೆ ಇದನ್ನು ತಿಳಿಯಲೇಬೇಕು. ಕರ್ಮದ ನಡೆ ಅತ್ಯಂತ\nರಹಸ್ಯವಾದದ್ದು. ಯಾವುದು ಕರ್ಮ ಯಾವುದು ಅಕರ್ಮ ಎಂದು ತಿಳಿಯುವುದು ಬಹಳ ಕಷ್ಟ. ದೊಡ್ಡದೊಡ್ಡ\nಜ್ಞಾನಿಗಳಿಗೂ ಇದು ತಿಳಿಯುವುದಿಲ್ಲ. ಇತಿಹಾಸದಲ್ಲಿನ ಕೆಲವು ವಿಷಯವನ್ನು ನೋಡಿದರೆ... ನಮಗೆ\nಗೊಂದಲವಾಗುತ್ತದೆ. ಉದಾಹರಣೆಗೆ ವೇದವ್ಯಾಸರು. ಇವರು ಮದುವೆ ಆಗದ ಒಬ್ಬ ಬೆಸ್ತರ ಹುಡುಗಿಯಿಂದ\nಹುಟ್ಟಿದ ಕನ್ಯಾಪುತ್ರ(ಕಾನೀನ); ವೇದವ್ಯಾಸರ ಮಕ್ಕಳು ಪಾಂಡು ಮತ್ತು ಧೃತರಾಷ್ಟ್ರ ವಿಧವೆಯರಿಗೆ ಹುಟ್ಟಿದ\nಮಕ್ಕಳು; ಪಾಂಡವರು-ಗಂಡ ಇರುವಾಗ ಪರಪುರುಷರಿಗೆ ಹುಟ್ಟಿದವರು! ಯಾವುದು ಧರ್ಮ? ಪಾಂಡವರನ್ನು\nಸಮರ್ಥಿಸುವುದು ಎಷ್ಟು ಸರಿ? ವೇದವ್ಯಾಸರನ್ನು ಮಹಾಜ್ಞಾನಿ ಬ್ರಾಹ್ಮಣ ಎಂದು ಒಪ್ಪುವುದು ಸಾಧ್ಯವೇ? ಈ\nಉದಾಹರಣೆಯನ್ನು ನೋಡಿದಾಗ ಯಾವುದು ಧರ್ಮ, ಯಾವುದು ಅಧರ್ಮ, ಯಾವುದು ಸರಿ, ಯಾವುದು ತಪ್ಪು,\nಎನ್ನುವಲ್ಲಿ ನಮಗೆ ಗೊಂದಲವಾಗುತ್ತದೆ.\n\nನಮ್ಮಲ್ಲಿ ನೆಡೆಯತಕ್ಕ ಕರ್ಮ, ಅಕರ್ಮ, ವಿಕರ್ಮದ ಹಿಂದೆ ಅನಂತವಾದ ಭಗವದ್‌ ಶಕ್ತಿ ಕೆಲಸ ಮಾಡುತ್ತಿರುತ್ತದೆ\nಎನ್ನುವ ಎಚ್ಚರ ನಮಗಿರಬೇಕು. ಈ ಜ್ಞಾನವಿಲ್ಲದೆ ಕರ್ಮದ ಮರ್ಮವನ್ನು ಅರಿಯಲು ಸಾಧ್ಯವಿಲ್ಲ. ಒಂದು\nದೇಹದಲ್ಲಿ ಭಗವಂತ ಅನೇಕ ರೂಪದಲ್ಲಿದ್ದು(ವಿಕರ್ಮಣಃ) ಕರ್ಮ ಮಾಡಿಸುತ್ತಾನೆ. ಕರ್ಮ ಎನ್ನುವುದು ತುಂಬಾ\nಕ್ಲಿಷ್ಟವಾದ ವಿಷಯ. ಅದನ್ನು ನಾವು ಭಗವಂತನಿಂದಲೇ ತಿಳಿಯಬೇಕು. ಮುಂದಿನ ಶ್ಲೋಕಗಳಲ್ಲಿ ಕೃಷ್ಣ ಕರ್ಮದ\nಮರ್ಮವನ್ನು ವಿವರಿಸುತ್ತಾನೆ.",
  "4.18": "ಕರ್ಮಣಿ ಅಕರ್ಮ ಯಃ ಪಶ್ಯೇತ್‌ ಅಕರ್ಮಣಿ ಚ ಕರ್ಮ ಯಃ |\nಸಃ ಬುದ್ಧಿಮಾನ್‌ ಮನುಷ್ಯೇಷು ಸಃ ಯುಕ್ತಃ ಕೃತ್ಸ್ನಕರ್ಮ ಕೃತ್‌ -- ವಿಶ್ವದ ಕ್ರಿಯೆ ನಡೆಯುತ್ತಿರುವಾಗಲೂ\nತನ್ನಿಂದ ಏನೂ ನಡೆದಿಲ್ಲ ಎಂದು ತಿಳಿದವನು, ತಾನು ಏನೂ ಮಾಡದಿದ್ದಾಗಲೂ ವಿಶ್ವದ ಕ್ರಿಯೆ ನಡೆಯುತ್ತಿದೆ\n\nಎಂದು ತಿಳಿದವನು,[ಕರ್ಮ ಬದ್ಧನಾದ ಜೀವನಲ್ಲಿ ಕರ್ಮ ಇಲ್ಲ ಎಂದು ತಿಳಿದವನು, ಕರ್ಮಾತೀತನಾದ\nಭಗವಂತನಲ್ಲಿ ಎಲ್ಲಾ ಕರ್ಮಗಳನ್ನು ಕಾಣುವವನು] ಮನುಷ್ಯರಲ್ಲಿ ನಿಜವಾಗಿ ತಿಳಿದವನು. ಅವನೇ ಸಾಧನೆಯ\nದಾರಿ ಬಲ್ಲವನು; ಎಲ್ಲಾ ಕರ್ಮಗಳ ಫಲವನ್ನು ಪಡೆದವನು.\n\nಕರ್ಮ ಅಂದರೆ ಏನು ಎನ್ನುವ ಬಗ್ಗೆ ಅತ್ಯಂತ ರೋಚಕವಾದ ವಿಚಾರವನ್ನು ಕೃಷ್ಣ ಇಲ್ಲಿ ವಿವರಿಸಿದ್ದಾನೆ. ಈ ಹಿಂದೆ\nಹೇಳಿದಂತೆ ಸಂಸ್ಕೃತ ರಹಸ್ಯಾರ್ಥವುಳ್ಳ ಭಾಷೆ. ಅದಕ್ಕಾಗಿ ಭಗವದ್ಗೀತೆಯನ್ನು\nಓದಿದಾಕ್ಷಣ, ಅಧ್ಯಾತ್ಮದ ಅನುಭವ ಇಲ್ಲದೆ ಏನೂ ತಿಳಿಯದು. ಅಧ್ಯಾತ್ಮದ ಅನುಭವದ ಸ್ಥರದಲ್ಲಿ ನಾವು ಎಷ್ಟು\nಆಳಕ್ಕೆ ಇಳಿಯುತ್ತೇವೋ ಅಷ್ಟು ಆಳಕ್ಕೆ ಗೀತೆ ತೆರೆದುಕೊಳ್ಳುತ್ತದೆ. ಇದಕ್ಕೆ ಈ ಶ್ಲೋಕವೇ ಉದಾಹರಣೆ.\nಮೇಲ್ನೊ ಟಕ್ಕೆ ಒಗಟಿನಂತೆ ವಿರೋಧಾಭಾಸವಾಗಿರುವ ಹುಚ್ಚು ಹೇಳಿಕೆಯಂತಿದೆ ಈ ಶ್ಲೋಕ! ಇಲ್ಲಿ ಹೀಗೆ\nಹೇಳಲಾಗಿದೆ: \"ಕರ್ಮ ಇದ್ದಲ್ಲಿ ಕರ್ಮ ಇಲ್ಲ, ಕರ್ಮ ಎಲ್ಲಿ ಇಲ್ಲ ಅಲ್ಲಿ ಕರ್ಮ ಇದೆ. ಇದು ಯಾರಿಗೆ ತಿಳಿದಿದೆಯೋ\nಆತ ಬುದ್ಧಿವಂತ” ಅಥವಾ \"ಯಾವುದು ಕರ್ಮವೋ ಅದು ಕರ್ಮವಲ್ಲ, ಯಾವುದು ಕರ್ಮವಲ್ಲವೋ ಅದು ಕರ್ಮ;\nಇದನ್ನು ತಿಳಿದವ ಬುದ್ಧಿವಂತ” ಇಲ್ಲಿರುವ ಗೂಡಾರ್ಥವನ್ನು ತಿಳಿದುಕೊಳ್ಳಬೇಕಾದರೆ ಅಧ್ಯಯನದ ಜೊತೆಗೆ\nಅಧ್ಯಾತ್ಮದ ಅನುಭಾವ ಬೇಕು.\n\n'ಎಲ್ಲಿ ಕರ್ಮವಿದೆಯೋ ಅಲ್ಲಿ ಕರ್ಮವಿಲ್ಲ'. ನಾವು ನಮ್ಮಲ್ಲಿ ಕರ್ಮವಿದೆ ಎಂದು ತಿಳಿದುಕೊಳ್ಳುತ್ತೇವೆ. 'ನನ್ನಲ್ಲಿ\nಕರ್ಮದ ಸ್ವಾತಂತ್ರ್ಯವಿದೆ-ನನಗೆ ಯಾರ ಹಂಗೂ ಇಲ್ಲ' ಎನ್ನುವ ಭಾವನೆ ನಮ್ಮದು. ಆದರೆ ನಮ್ಮಲ್ಲಿರುವ ಕರ್ಮ\nಭಗವಂತನ ಅಧೀನ. ಈ ಸೃಷ್ಟಿ ಚಕ್ರದಲ್ಲಿ ನಾವು ಏನೂ ಮಾಡದಿದ್ದಾಗಲೂ ಸಹ ಕ್ರಿಯೆ ನಿರಂತರವಾಗಿ\nನಡೆಯುತ್ತಿರುತ್ತದೆ. ನೀನು ಏನನ್ನಾದರೂ ಮಾಡುತ್ತಿದ್ದರೆ ನಿನ್ನಿಂದಾಗಿಯೇ ಕ್ರಿಯೆ ನಡೆದದ್ದಲ್ಲ. ನನ್ನಲ್ಲಿ ಕ್ರಿಯೆ ಇದೆ\nಎನ್ನುವ ಭ್ರಮೆಯನ್ನು ಬಿಟ್ಟುಬಿಡು. ಪ್ರಕೃತಿ ನಿರಂತರವಾಗಿ ತನ್ನ ಕರ್ತವ್ಯವನ್ನು ಮಾಡುತ್ತಿರುತ್ತದೆ. ವಿಶ್ವಕ್ರಿಯೆ\nನಾವು ನಿಷ್ಕ್ರೀಯರಾಗಿದ್ದರೂ ನಡೆಯುತ್ತದೆ. ನಾವು ಎಲ್ಲಾ ಮಾಡಿದರೂ ಏನೂ ನಡೆಯುವುದಿಲ್ಲ. ಈ ವಿಶ್ವಚಕ್ರ\nನಿರಂತರ.\n\nಇದನ್ನು ಅರ್ಥ ಮಾಡಿಕೊಳ್ಳಲು ಒಂದು ಲೌಕಿಕ ದೃಷ್ಟಾಂತವನ್ನು ನೋಡೋಣ. ಒಂದು ಆನೇ(ಈ ವಿಶ್ವ ಚಕ್ರ)\nಅದರ ತಲೆಯ ಮೇಲೆ ಒಂದು ಪುಟ್ಟ ಇರುವೈ(ಸಾಮಾನ್ಯ ಮಾನವ). ಆನೆ ಪೂರ್ವದಿಂದ ಪಶ್ಚಿಮಕ್ಕೆ ಹೋಗುತ್ತಿದೆ.\nಇರುವೆ ನಿರಂತರ ತಲೆಯಿಂದ ಬಾಲದತ್ತ ಅಂದರೆ ಪಶ್ಚಿಮದಿಂದ ಪೂರ್ವಕ್ಕೆ ಹೋಗುತ್ತಿದೆ. ಆದರೆ ಆನೆಯ ಮೇಲೆ\nಇರುವ ಈ ಇರುವೆ ಯಾವ ದಿಕ್ಕಿನಲ್ಲಿ ಚಲಿಸಿದರೂ, ಅದು ಆನೆ ಎಲ್ಲಿಗೆ ಸೇರುತ್ತದೋ ಅಲ್ಲಿಗೇ ಸೇರುವುದು. ಇಲ್ಲಿ\nಇರುವೆಯ ಚಲನೆ ವ್ಯರ್ಥ-ಅದರಿಂದ ಏನೂ ಉಪಯೋಗವಿಲ್ಲ. ಒಂದು ವೇಳೆ ಈ ಇರುವೆ ನನ್ನಿಂದಾಗಿ ಆನೆ\nಅಲ್ಲಿಂದ ಇಲ್ಲಿಗೆ ಬಂದು ತಲುಪಿತು ಎಂದು ತಿಳಿದರೆ? ಎಷ್ಟು ಹಾಸ್ಯಾಸ್ಟ ದವಲ್ಲವೇ? ಹಾಗೇ, ನಮ್ಮ ಚಲನೆಯ\nಹಿಂದೆ ಒಂದು ಮಹಾನ್‌ ಚಾಲನಾ ಶಕ್ತಿ ಇದೆ. ಇಡೀ ಬ್ರಹ್ಮಾಂಡವನ್ನು ತೆಗೆದುಕೊಂಡರೆ, ಈ ಭೂಮಿ\nಇತರ ಗ್ರಹಗೋಲಗಳ ನಡುವಿನ ಒಂದು ಚಿಕ್ಕ ಬಿಂದು. ಆ ಬಿಂದುವಿನಲ್ಲಿ ನಮ್ಮ ದೇಶ ಇನ್ನೂ ಒಂದು ಚಿಕ್ಕ\nಬಿಂದು. ಅದರಲ್ಲಿ 'ನಾನು' ಎನ್ನುವುದು ಊಹಿಸಲೂ ಅಸಾಧ್ಯವಾದ ಬಿಂದು (fraction of a point in the universe).\nಆದರೆ ನಾವು ಮಾತ್ರ ಈ ಬ್ರಹ್ಮಾಂಡವೇ ನಮ್ಮಿಂದ ನಡೆಯುತ್ತಿದೆ ಎನ್ನುವಂತೆ ಅಹಂಕಾರ ಪಡುತ್ತೇವೆ. ಇಡೀ\nವಿಶ್ವದ ಚಲನೆಯೊಂದಿಗೆ ನಾವು. ಒಂದು ಘಟಕವಾಗಿದ್ದೇವೆಯೇ ಹೊರತು, ನಮ್ಮ ಸ್ವಂತದಿಂದ ಏನೂ\n\nಆಗುತ್ತಿಲ್ಲ. ಆದ್ದರಿಂದ 'ನಿನ್ನ ಕರ್ಮದಲ್ಲಿ ಅಕರ್ಮವನ್ನು ನೋಡು' ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಹೀಗೆ ತನ್ನ ಕರ್ಮವನ್ನು\nನಿಯಂತ್ರಿಸುವ ವಿಶ್ವಶಕ್ತಿಯಾಗಿ ಭಗವಂತನಿದ್ದಾನೆ ಎಂದು ತಿಳಿದವ ವಿವೇಕಿ'.\n'ಯುಕ್ತಃ' ಅಂದರೆ ಮನಸ್ಸನ್ನು ಸತ್ಯದ ಕಡೆಗೆ ತಿರುಗಿಸಿ, ಸತ್ಯವನ್ನು ತಿಳಿಯುವುದಕ್ಕೋಸ್ಕರ ಮನನ ಮಾಡಿದವ\nಎಂದರ್ಥ. ಹೀಗೆ ಸರಿ ತಪ್ಪು ತಿಳಿದವ ಎಲ್ಲಾ ಕರ್ಮದ ಪೂರ್ಣ ಫಲವನ್ನು ಪಡೆಯುತ್ತಾನೆ. ಇಂತವನಿಗೆ ಕರ್ತೃತ್ವ\nಇದ್ದರೂ ಅದರ ಅಭಿಮಾನವಿಲ್ಲ; ನಾನು ಮಾಡಿದೆ ನನ್ನಿಂದಾಯಿತು ಅನ್ನುವ ಅಹಂಕಾರವಿಲ್ಲ; ನಾನು ಸ್ವತಂತ್ರ\nಅನ್ನುವ ಭ್ರಮೆ ಇಲ್ಲ. ಆದ್ದರಿಂದ ಅವನು ಮಾಡುವ ಎಲ್ಲಾ ಕರ್ಮವೂ ಫಲಪ್ರದ. ಭಗವಂತನ ಪಾರಮ್ಯದ\nಎಚ್ಚರದಿಂದ ಅವನ ಜೀವನ ರೂಪುಗೊಂಡಿದೆ. ಅಂತವನು ಸಣ್ಣ ಕರ್ಮ ಮಾಡಿದರೂ ಮಹಾಫಲವನ್ನು\nಪಡೆಯುತ್ತಾನೆ. ಅಹಂಕಾರದಿಂದ ಕಳಚಿಕೊಳ್ಳುವುದು ಅಧ್ಯಾತ್ಮದಲ್ಲಿ ಅತ್ಯಂತ ಮಹತ್ವದ ವಿಷಯ. ಕೃಷ್ಣ\nಗೀತೆಯಲ್ಲಿ ಈ ಮಾತನ್ನು ಪದೇ ಪದೇ ಹೇಳುತ್ತಾನೆ. ಅಹಂಕಾರ ಎನ್ನು ವುದು ಎಷ್ಟು ಅಪಾಯಕಾರಿ ಎಂದರೆ,\nಗೀತೆ ಓದಿದ ಮೇಲೆ 'ನಾನು ಗೀತೆಯನ್ನು ಓದಿದ್ದೇನೆ' ಎನ್ನುವ ಅಹಂಕಾರ ಬಂದು ಬಿಡುತ್ತದೆ! ಆದ್ದರಿಂದ ಜ್ಞಾನ\nಸಂಪಾದನೆ ಜೊತೆಗೆ ಒಂದು ಎಚ್ಚರ ಸದಾ ಇರಬೇಕು. ಯಾವ ಕಾಲಕ್ಕೂ ಅಹಂಕಾರಕ್ಕೆ ಒಳಗಾಗಬಾರದು.\nಅಹಂಕಾರ ಎನ್ನುವುದು ಅಧ್ಯಾತ್ಮದ ದಾರಿ ಅಲ್ಲ.\nಭಗವಂತ ಕರ್ಮ ಮಾಡಿದರೂ ಅವನಿಗೆ ಕರ್ಮದ ಲೇಪವಿಲ್ಲ. ಯಾವದೇ ಕರ್ಮಲೇಪವಿಲ್ಲದ ಭಗವಂತನಲ್ಲಿ\nಎಲ್ಲಾ ಕರ್ಮವಿದೆ. ಕರ್ಮ ಇದ್ದಲ್ಲಿ ಕರ್ಮದ ಲೇಪವಿಲ್ಲವೋ. ಯಾರಲ್ಲಿ ಕರ್ಮದ ಲೇಪವಿಲ್ಲ ಆತ ಮಾತ್ರ ಪೂರ್ಣ\nಫಲವನ್ನು ಪಡೆಯುತ್ತಾನೆ. ಕರ್ಮದ ಲೇಪದಲ್ಲಿ ಬಿದ್ದವನು 'ನಾನು ಮಾಡಿದೆ, ನನ್ನಿಂದಾಯಿತು' ಎಂದುಕೊಂಡು\nಸೆರೆಯಲ್ಲಿ ಸಿಕ್ಕಿ ಒದ್ದಾಡುತ್ತಾನೆ. ಇದು ಕೃಷ್ಣನ ಕರ್ಮದ ವಿವರಣೆ. ಭಗವಂತನಲ್ಲಿ ಕರ್ಮದ\nಲೇಪವಿಲ್ಲ, ಆದರೆ ಸರ್ವ ಕರ್ತ್ಯತ್ವವಿದೆ. ನಾವು ಎಷ್ಟು ಕರ್ಮದ ಲೇಪವನ್ನು ಕಮ್ಮಿ ಮಾಡಿಕೊಂಡೆವೋ ಅಷ್ಟು\nಕರ್ಮದ ಫಲವನ್ನು ಪಡೆಯುತ್ತೇವೆ. ಇದನ್ನು ತಿಳಿದವ ಬುದ್ಧಿವಂತ. ಆತ... ಕರ್ಮದ ನಿಜವಾದ\nಅನುಸಂಧಾನದಿಂದ ಅದರ ಪೂರ್ಣ ಫಲವನ್ನು ಪಡೆಯುತ್ತಾನೆ. ಇದನ್ನು ಇನ್ನೂ ಬಿಡಿಸಿ ಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ\nಕೃಷ್ಣ ವಿವರಿಸುತ್ತಾನೆ.\n",
  "4.19": "ಯಸ್ಯ ಸರ್ವೇ ಸಮಾರಂಭಾಃ ಕಾಮ ಸಂಕಲ್ಪವರ್ಜಿತಾಃ\nಜ್ಞಾನ ಅಗ್ನಿ ದಗ್ಧ ಕರ್ಮಾಣಮ್‌ ತಮ್‌ ಆಹುಃ ಪಂಡಿತಮ್‌ ಬುಧಾಃ -- ಮಾಡುವ ಬಯಕೆ, ಪಡೆಯುವ\nಬಯಕೆಗಳನ್ನು ತೊರೆದು ಎಲ್ಲಾ ಕರ್ಮಗಳಲ್ಲೂ ತೊಡಗುವವನು ಅರಿವಿನ ಬೆಂಕಿಯಿಂದ ಕರ್ಮಗಳನ್ನು\nಸುಟ್ಟವನು. ಬಲ್ಲವರು ಅಂಥವನನ್ನು ಪಂಡಿತ ಎನ್ನುತ್ತಾರೆ.\n\nನಮ್ಮ ಜೀವನದ ತೊಡಗುವಿಕೆಯ ಹಿಂದೆ ಒಂದು ಕಾಮನೆ,ಸಂಕಲ್ಪ ಇರುತ್ತದೆ. ನಾನು ಸುಖ ಪಡಬೇಕು, ನನ್ನ\nಮನೆಮಂದಿಯನ್ನು ಸುಖವಾಗಿಡಬೇಕು ಎನ್ನು ವ. ಕಾಮನೆ. ಇದಕ್ಕಾಗಿ ಇನ್ಯಾವುದೋ ವಿಧಾನವನ್ನು\n\nಅನುಸರಿಸುತ್ತೇವೆ. ಇದು ಪ್ರತಿಯೊಂದು ಕ್ರಿಯೆಯ ಹಿಂದೆ ಮನುಷ್ಯನನ್ನು ಕಾಡುವ ಸಮಸ್ಯೆ. ತನ್ನ ಬಯಕೆಯ\nಈಡೇರಿಕೆಗಾಗಿ ನಮ್ಮನ್ನು ನಾವು ತೊಡಗಿಸಿಕೊಳ್ಳುತ್ತೇವೆ. ಯಾರಿಗೆ ತನ್ನ ತೊಡಗುವಿಕೆಯಲ್ಲಿ ಬಯಕೆಗಳ ಸ್ಪರ್ಶ\nಇಲ್ಲವೋ ಅವನು ಪಂಡಿತ. ಒಬ್ಬ ಪಂಡಿತನ ಪಾಂಡಿತ್ಯವನ್ನು ಅವನ ನುಡಿಯಲ್ಲಿ ಅಲ್ಲ, ನಡೆಯಲ್ಲಿ ಕಾಣಬೇಕು.\nನಿನ್ನ ಜೀವನದಲ್ಲಿ ಹೀಗೇ ಆಗಬೇಕು, ಹೀಗೇ ಮಾಡಬೇಕು, ಅದರಿಂದ ಇಂತಹದ್ದೇ ಸಿಗಬೇಕು ಅನ್ನು ವ ಬಯಕೆ,\nಆಸೆಗಳನ್ನು ಬಿಟ್ಟು ನಿರಾಳವಾಗಿ ಕರ್ತವ್ಯ ಮಾಡು. ಭಗವಂತ ಏನು ಕೊಡುತ್ತಾನೆ ಅದನ್ನು ಪ್ರಸಾದವಾಗಿ\nಸ್ವೀಕರಿಸು. ಏನು ಬಂತೋ ಅದರಲ್ಲಿ ತೃಪ್ತಿಪಡುವುದನ್ನು ಕಲಿ. ಇಲ್ಲವಲ್ಲಾ ಎಂದು ಸಂಕಟ ಪಡಬೇಡ. ಇದು\n'ಕಾಮಸಂಕಲ್ಪ ವರ್ಜ್ಯ. [ಏನೂ ಬೇಡ ಎಂದು ಬಯಸುವುದಲ್ಲ, ಇಂತದ್ದೇ ಬೇಕು ಎಂದು ಬಯಸದೇ ಇರುವುದು\nಕಾಮಸಂಕಲ್ಪ ವರ್ಜ್ಯ]. ಏನು ಬಂತೋ ಬರಲಿ, ನೀನು ಪ್ರಯತ್ನ ಶೀಲನಾಗು. ಬಂದದ್ದರಲ್ಲಿ ಸಂತೋಷದಿಂದ\nಬದುಕು. ಇಂತಹ ಅರಿವಿನಿಂದ ಮಾಡಿದ ಕರ್ಮ ಸ್ವಚ್ಛವಾಗಿರುತ್ತದೆ. ಇದು ಕರ್ಮದ ಕೊಳೆ ಅರಿವಿನ ಬೆಂಕಿಯಿಂದ\nಸ್ವಚ್ಛವಾಗುವಿಕೆ. ಇಂತಹ ನಡೆ ಉಳ್ಳವನು ಪಂಡಿತ ಎನಿಸುತ್ತಾನೆ. ಇಂತವರನ್ನು ಜ್ಞಾನಿಗಳು “ಜ್ಞಾನಿಗಳೆಂದು'\nಗುರುತಿಸುತ್ತಾರೆ. ಮನುಷ್ಯ ಏನನ್ನು ಹೇಳುತ್ತಾನೆ ಅದು ಮುಖ್ಯವಲ್ಲ, ಏನನ್ನು ರೂಢಿಸಿಕೊಳ್ಳುತ್ತಾನೆ ಅದು\nಮುಖ್ಯ. ಮನಸ್ಸಿನ ತುಂಬಾ ಆಸೆಗಳನ್ನು ತುಂಬಿಕೊಂಡು ಯಾವುದ್ಯಾವುದೋ ಆಸೆಯ ಬೆನ್ನುಹತ್ತಿ ಸೋಗು\nಹಾಕಿಕೊಂಡು ಬದುಕುವವನು ಎಂದೂ ಎತ್ತರಕ್ಕೇರಲಾರ.\n",
  "4.20": "ತ್ಯಕ್ತ್ವಾ ಕರ್ಮ ಫಲ ಅಸಂಗಮ್‌ ನಿತ್ಯ ತೃಪ್ಪಃ [ಅ]ನಿರಾಶ್ರಯಃ\n\nಕರ್ಮಣಿ ಅಭಿಪ್ರವೃತ್ತಃ ಅಪಿ ನ ಏವ ಕಿಂಚಿತ್‌ ಕರೋತಿ ಸಃ -- ಕರ್ಮಫಲದಲ್ಲಿ ನೇಹವನ್ನು ತೊರೆದು, ತಾನು\nಎಂದೂ ಇತರ ಬಯಕೆ ಇಲ್ಲದ, ಯಾರಿಗೂ ತಲೆಬಾಗದ ಭಗವಂತನ ಪಡಿಯಚ್ಚು ಎಂದು\nತಿಳಿದವನು[ಭಗವಂತನ ಆಸರೆಯಲ್ಲಿದ್ದು ಸದಾ ನೆಮ್ಮದಿಯಿಂದಿರುವವನು] ಕರ್ಮದಲ್ಲಿ ತೊಡಗಿದರೂ\nವಾಸ್ತವವಾಗಿ ಏನನ್ನೂ ಮಾಡುವುದಿಲ್ಲ.\n\nಕೆಲವರಿಗೆ ಅದು ಬೇಕು, ಇದು ಬೇಕು ಎನ್ನು ವ ಆಸೆ ಇರುವುದಿಲ್ಲ. ಆದರೆ ಬಂದಾಗ ಖುಷಿಯಾಗುತ್ತದೆ. ಕರ್ಮ\nಫಲದಲ್ಲಿ ಅತಿಯಾದ ಸ್ನೇಹ ಒಳ್ಳೆಯದಲ್ಲ. ಭಗವಂತ ಪ್ರೇರಣೆ ಮಾಡಿದ ಬಂತು. ಅದನ್ನು ಸದ್ವಿನಿಯೋಗ\nಮಾಡುವುದು ಹೇಗೆ ಎನ್ನುವುದನ್ನು ಯೋಚಿಸು; ಉಬ್ಬಬೇಡ. ಬರಬೇಕು ಎಂದು ನಿರೀಕ್ಷಿಸಬೇಡ, ನಿರೀಕ್ಷಿಸದೇ\nಬಂದಾಗ ಹಾರಾಡಬೇಡ. ಫಲದ ಬಗ್ಗೆ ಅತಿಯಾದ ಮಮತೆ ಒಳ್ಳೆಯದಲ್ಲ. ಇದೊಂದೇ ಮನುಷ್ಯ ಹಾಯಾಗಿ\nನೆಮ್ಮದಿಯಿಂದ ಬದುಕಲು ಇರುವ ವಿಧಾನ. ಇದು ಇಲ್ಲದಿದ್ದರೆ ಹತಾಶೆ . ಅದರಿಂದ ಮಾನಸಿಕ\n\nವ್ಯಾಕುಲತೆ . ಇನ್ನು ಅಕಾಲದಲ್ಲಿ ಸಂಪತ್ತು ಬಂದಾಗ ಹಾರಾಟ-ಅದರಿಂದ ಜೀವನ ನಾಶ! ಈ\n\nಕಾರಣದಿಂದ ಬಂತು ಎಂದಾಗಲೀ, ಬರಲಿಲ್ಲ ಎಂದಾಗಲೀ, ಬರಬೇಕು ಎಂದಾಗಲೀ ತಲೆ ಕೆಡಿಸಿಕೊಳ್ಳಬೇಡ.\nಸ್ವಚ್ಛವಾದ ಯೋಚನೆಯಿಂದ ಕರ್ತವ್ಯದಲ್ಲಿ ತೊಡಗು. ಎಂತಹ ಪರಿಸ್ಥಿತಿಯಲ್ಲೂ ಸಂಯಮ ಇರಲಿ. ಈ ರೀತಿ\nನಿನ್ನ ಮನಸ್ಸನ್ನು ತರಬೇತಿಗೊಳಿಸು ಎಂದಿದ್ದಾನೆ ಕೃಷ್ಣ. ಇದು ಕೃಷ್ಣನ ಮನಃಶಾಸ್ತ್ರ.\n\nಜೀವ ಭಗವಂತನ ಪ್ರತಿಬಿಂಬ. ಅದಕ್ಕೆ ಸ್ವಾತಂತ್ರ್ಯವಿಲ್ಲ. ಬಿಂಬ ಮಾಡಿಸಿದಂತೆ ಪ್ರತಿಬಿಂಬ. ಭಗವಂತ ನಿತ್ಯ\nತೃಪ್ತ, ಆತನಿಗೆ ಅತೃಪ್ತಿ ಇಲ್ಲ. ಹಾಗೇ ನಾವೂ ಕೂಡಾ ಅತೃಪ್ತಿ ಇಲ್ಲದೆ ಬದುಕುವುದನ್ನು ಕಲಿತುಕೊಳ್ಳಬೇಕು.\nಯಾವುದೋ ಒಂದು ಆಸೆ ಈಡೇರಿಸಿಕೊಳ್ಳುವುದಕ್ಕಾಗಿ ಎಷ್ಟೋ ಜನರ ಹಿಂದೆ ಬಾಲ ಅಲ್ಲಾಡಿಸಿಕೊಂಡು\nಸ್ವಾರ್ಥ ಮನಸ್ಸಿನಿಂದ ಬದುಕುವುದು ಜೀವನವಲ್ಲ. ಯಾರ ಆಶ್ರಯವೂ ಇಲ್ಲದಿರುವ ಭಗವಂತನ\nಪ್ರತಿಬಿಂಬವಾದ ನಿನಗೆ ಅತೃಪ್ತಿಯ ಬದುಕೇಕೆ? ಭಗವಂತನಂತೆ ನಿರಾಶ್ರಯನಾಗು. ನಿನಗೆ ಸದಾ ಭಗವಂತನ\nಆಶ್ರಯವಿದೆ ಎನ್ನುವ ಸತ್ಯವನ್ನು ಅರಿತು ಬಾಳು. ಹೀಗೆ ಬದುಕುವ ಮಾನವ ಕರ್ಮದಲ್ಲಿ ತೊಡಗಿದ್ದರೂ ಕೂಡಾ\nಏನನ್ನೂ ಮಾಡುವುದಿಲ್ಲ. ಏಕೆಂದರೆ ಭಗವಂತ ಎಲ್ಲವುದಕ್ಕೆಂತ ಮೇಲಿದ್ದಾನೆ ಎನ್ನುವ ಮರ್ಮವನ್ನು ಆತ\nಅರಿತಿರುತ್ತಾನೆ. ಇದಕ್ಕೆ ಇನ್ನೂ ಹೆಚ್ಚಿನ ವಿವರಣೆಯನ್ನು ಮುಂದಿನ ಶ್ಲೋಕಗಳಲ್ಲಿ ಕಾಣಬಹುದು.\n",
  "4.21": "ನಿರಾಶೀಃ ಯಶ ಚಿತ್ತ ಆತ್ಮಾ ತ್ಯಕ್ತ ಸರ್ವ ಪರಿಗ್ರಹಃ |\n\nಶಾರೀರಮ್‌ ಕೇವಲಮ್‌ ಕರ್ಮ ಕುರ್ವನ್‌ ನ ಆಪ್ನೋತಿ ಕಿಲ್ಬಿಷಮ್‌ -- ಮನಸ್ಸು -ಚಿತ್ತಗಳನ್ನು ಹದ್ದಿನಲ್ಲಿರಿಸಿದಾಗ\nಹಂಬಲ ದೂರವಾಗುತ್ತದೆ. ನಾನು-ನನ್ನದು ಎಂಬ ಭಾವ ಮರೆಯಾಗುತ್ತದೆ. ದೇಹ ಪೋಷಣೆಗಷ್ಟೇ ಕರ್ಮ\nಮಾಡಿದರೂ ದೋಷ ತಟ್ಟುವುದಿಲ್ಲ.\n\nನಿತ್ಯತೃಪ್ತರಾಗಿರಬೇಕು ಅನ್ನುವ ಆಸೆ ಇದೆ ಆದರೆ ಅದನ್ನು ರೂಢಿಸಿಕೊಳ್ಳುವುದು ಹೇಗೆ? ಈ ಪ್ರಶ್ನೆಗೆ ಇಲ್ಲಿ ಕೃಷ್ಣ\nಉತ್ತರಿಸುತ್ತಾನೆ. ಲೌಕಿಕ ಆಸೆ ಇದ್ದಾಗ ಅತೃಪ್ತಿ ತಪ್ಪಿದ್ದಲ್ಲ. ಇಲ್ಲದ್ದನ್ನು ಬಯಸಿ ಎಂದೂ ಸುಖ ಸಿಗುವುದಿಲ್ಲ. ತೃಪ್ತಿ\nಇರಬೇಕಾದರೆ ಮೊದಲು ಬೇಕು ಬೇಡಗಳ ಪಟ್ಟಿಯನ್ನು ಕಡಿಮೆ ಮಾಡಬೇಕು. ಮೊದಲು 'ಯಶಚಿತ್ತನಾಗು'\nಅದರಿಂದ 'ನಿರಾಶಿಯಾಗು' (desireless) ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಮೊದಲು ನಾವು\nನಮ್ಮ ಚಿತ್ತವನ್ನು ಮತ್ತು ಮನಸ್ಸನ್ನು ನಿಯಂತ್ರಣದಲ್ಲಿಟ್ಟುಕೊಳ್ಳಬೇಕು. ಇಲ್ಲಿ ಚಿತ್ತ ಎಂದರೆ ನಮ್ಮ ಹಿಂದಿನ\nನೆನಪುಗಳು. ಹಿಂದೆ ಮೂಡಿದ ಆಸೆಗಳ ನೆನಪಿನಕೋಶ-ಚಿತ್ತ. ಚಿತ್ತದಲ್ಲಿ ಆಸೆ ನಿರಾಸೆಗಳ ಕಂತೆ\nತುಂಬಿರುತ್ತದೆ. ಮೊದಲು ಹಿಂದಿನ ಆಸೆಗಳು ಮರುಕಳಿಸದಂತೆ ನೋಡಿಕೋ. ಭೂತಕಾಲವನ್ನು ಮತ್ತೆ\nಕೆದುಕಬೇಡ. ಅದನ್ನು ಪೂರ್ತಿ ಬಿಟ್ಟುಬಿಡು ಹಾಗೂ ಮನಸ್ಸು ವರ್ತಮಾನ ಕಾಲದಲ್ಲಿ ಬೇಕು ಬೇಡಗಳೆಡೆಗೆ\nಹರಿಯದಂತೆ ನಿಯಂತ್ರಣ ಮಾಡು. ಈ ರೀತಿ ನಾವು ರೂಢಿ ಮಾಡಿಕೊಂಡರೆ ಇದರಿಂದ ತೃಪ್ತರಾಗಿರಲು ಸಾಧ್ಯ.\nಹೀಗೆ ತೃಪ್ತಿಯನ್ನು ಸಾಧಿಸಿದ ನಂತರ ಅದರ ಜೊತೆಗೆ 'ಆತ್ಮಾತ್ಯಕ್ತ ಸರ್ವ ಪರಿಗ್ರಹಃ'. ಇಲ್ಲಿ ಪರಿಗ್ರಹ ಎಂದರೆ\nಸಂಸಾರ, ಕುಟುಂಬ, ಎಲ್ಲವನ್ನೂ ಬಿಟ್ಟು ಕಾಡಿಗೆ ಹೋಗುವುದಲ್ಲ. ಎಲ್ಲವುದರ ಜೊತೆಗೆ ಇದ್ದೂ ಅದರ ಮೇಲಿನ\n\nಅತೀವ. ಮೋಹವನ್ನು ಬಿಟ್ಟುಬಿಡುವುದು. ಅಭಿಮಾನ ತ್ಯಾಗ (detached attachment) ಮಾಡುವುದು. ಎಲ್ಲವೂ ಇರಲಿ ಆದರೆ ಅದನ್ನೇ ಹಚ್ಚಿಕೊಂಡು ಅದರಲ್ಲೇ ಮುಳುಗಬೇಡ.\nಅದರೊಂದಿಗೆ ಬದುಕು- ಆದರೆ ಅಂಟಿಸಿಕೊಳ್ಳಬೇಡ. ತಾವರೆಯ ಎಲೆ ಹೇಗೆ ನೀರಿನಲ್ಲೇ ಇದ್ದು ನೀರನ್ನು\nಅಂಟಿಸಿಕೊಳ್ಳುವುದಿಲ್ಲವೋ ಹಾಗೆ. ಹೀಗೆ ಇದ್ದಾಗ ನಾವು ಎಲ್ಲಾ ಮಾಡಿದರೂ ಏನೂ ಮಾಡುವುದಿಲ್ಲ. ಏಕೆಂದರೆ\nಅರಿವಿನಿಂದ ಮಾಡಿದಾಗ ಕರ್ಮದ ಲೇಪವಿಲ್ಲ. ನಾವು ಅಂಟಿಸಿಕೊಳ್ಳದೇ ಬದುಕಲು ಕಲಿತರೆ ಕರ್ಮ ಕೂಡಾ\nನಮಗೆ ಅಂಟುವುದಿಲ್ಲ. ಶರೀರ ನಿರ್ವಹಣೆಗೆ ಬೇಕಾದ ಕರ್ಮವನ್ನು ಮಾನಸಿಕವಾಗಿ ಅಂಟಿಸಿಕೊಳ್ಳದೇ, ಬಡಾಯಿ\nಇಲ್ಲದೇ ಕರ್ಮ ನಿರ್ವಹಿಸು. ಆಗ ಕರ್ಮದ ಕೊಳೆ ನಿನಗಂಟುವುದಿಲ್ಲ ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.\n\nಯದೃಚ್ಛಾಲಾಭಸಂತುಷ್ಟೋ ದ್ವಂದ್ವಾತೀತೋ ವಿಮತ್ಸ ರಃ ।\n\nಸಮಃ ಸಿದಾವಸಿದೌ ಚ ಕೃತ್ಹಾ *ಪಿನನಿಬದಧದ ತೇ",
  "4.22": "ಛಿ ಛ ಛೆ ಧ್ಯೀ\n\nಯದೃಚ್ಛಾ ಲಾಭ ಸಂತುಷ್ಟಃ ದ್ವಂದ್ವ ಅತೀತಃ ವಿಮತ್ಸರಃ |\n\nಸಮಃ ಸಿದ್ಧೌ ಅಸಿದ್ದೌ ಚ ಕೃತ್ವಾ ಅಪಿ ನ ನಿಬಧ್ಯತೇ -- ತಾನಾಗಿಯೇ ಸಿಕ್ಕಿದ್ದುದರಲ್ಲಿ ಸಂತಸಪಡುವವನು,\nಬದುಕಿನ ಇಬ್ಬಂದಿತನವನ್ನು ಮೀರಿನಿಂತವನು, ಹೆರವರ ಏಳಿಗೆಗೆ ಕಿಚ್ಚುಪಡದವನು, ಗಳಿಕೆಯನ್ನೂ\nಕಲಿಕೆಯನ್ನೂ ಒಂದೇ ಬಗೆಯಿಂದ ಕಾಣುವವನು ಕರ್ಮ ಮಾಡಿದರೂ ಅದರ ಸೆರೆಗೆ ಸಿಕ್ಕುವುದಿಲ್ಲ.\n\nನಮ್ಮ ಮನಸ್ಸು ನಮ್ಮ ಹಿಡಿತಕ್ಕೆ ಬಂದಾಗ ಕಾಣುವ ಮುಖ್ಯ ಲಕ್ಷಣದ ಬಗ್ಗೆ ಇಲ್ಲಿ ವಿವರಣೆ ಇದೆ. ತೃಪ್ತಿಯನ್ನು\nಸಾಧಿಸಿದವನಿಗೆ ಏನಾದರೂ ಸಿಕ್ಕಿದರೆ ಅದರಲ್ಲೇ ಸಂತೋಷವಾಗಿರುತ್ತಾನೆ. ಸಿಕ್ಕಿದ್ದು ಸಾಲದೆಂದಾಗಲೀ,\nಇನ್ನೇನೋ ಸಿಗಲಿ ಎಂದಾಗಲೀ ಆತನ ಮನಸ್ಸು ಬಯಸುವುದಿಲ್ಲ. ಏಕೆಂದರೆ ನಮಗೆ ಏನೇ ಸಿಕ್ಕಿದರೂ ಅದು\nಭಗವಂತನ ಇಚ್ಛೆಯಿಂದ ಸಿಕ್ಕಿರುವುದು. ಉದಾಹರಣೆಗೆ ಉದ್ಯೋಗ. ಪ್ರತಿಭೆ ಇದ್ದವರಿಗೆಲ್ಲಾ ಉದ್ಯೋಗ\nಸಿಗುವುದಿಲ್ಲ. ಉದ್ಯೋಗ ಸಿಗುವುದು, ಅದರಿಂದ ಸಂಬಳ ಸಿಗುವುದು- ಎಲ್ಲವೂ ಭಗವಂತನ ಇಚ್ಛೆಯಂತೆ.\nಆದ್ದರಿಂದ ಎಲ್ಲವೂ ಭಗವಂತನ ಸಂಕಲ್ಪ ಎಂದು ತಿಳಿದು ನಿಸ್ವಾರ್ಥ ಕರ್ಮದಲ್ಲಿ ತೊಡಗಿದಾಗ ಮನಸ್ಸು\nನಿರ್ಮಲವಾಗುತ್ತದೆ. ಈ ಸ್ಥಿತಿಯಲ್ಲಿ ಅಹಂಕಾರ ಎಂದೂ ಹತ್ತಿರ ಸುಳಿಯುವುದಿಲ್ಲ. ಬಡತನವಾಗಲೀ,\nಸಿರಿತನವಾಗಲೀ, ನಾವು ಹುಟ್ಟುವ ಮನೆಯಾಗಲೀ, ಯಾವುದೂ ನಮ್ಮ ಕೈಯಲ್ಲಿಲ್ಲ. ಎಲ್ಲವೂ ಆ ಈಶ್ವರ ಇಚ್ಛೆ.\nಇದನ್ನು ತಿಳಿದು ಬದುಕುವುದು ಯಶಚಿತ್ತಾತ್ಮನ ಗುರುತು.\n\nಇನ್ನು ಎರಡನೇ ಲಕ್ಷಣ 'ದ್ವಂದ್ವಾತೀತ ಜೀವನ\". ನಮ್ಮ ಜೀವನ ಎಂದರೆ ದ್ವಂದ್ವ. ಹಗಲು-ರಾತ್ರಿ, ಲಾಭ-ನಷ್ಟ ಸ;\nಸೋಲು-ಗೆಲುವು, ಹುಟ್ಟು-ಸಾವು ಹೀಗೆ ಎಲ್ಲವೂ ದ್ವಂದ್ವ. ನಾವು ಈ ದ್ವಂದ್ವದ ನಡುವೆಯೇ ಬದುಕಬೇಕು.\nಹಗಲು-ರಾತ್ರಿಗೆ ನಾವು ಹೇಗೆ ಹೊಂದಿಕೊಂಡು ಬದುಕುತ್ತೇವೆಯೋ ಹಾಗೇ 'ಇತರ ದ್ವಂದ್ವದ ಆಘಾತಕ್ಕೆ\nಒಳಗಾಗದೇ ಬದುಕಲು ಕಲಿ' ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಸಿಗದಿದ್ದಾಗ ದುಃಖವಿಲ್ಲ, ಸಿಕ್ಕಾಗ ಹಾರಾಟವಿಲ್ಲ. ಎರಡೂ\nಸ್ಥಿತಿಯಲ್ಲಿ ಏಕರೂಪವಾದ ಮನಃಸ್ಥಿತಿಯನ್ನು ಗಳಿಸುವುದು ದ್ವಂದ್ವಾತೀತ ಜೀವನ.\n\nದ್ವಂದ್ವಾತೀತನಾಗಿ ಬದುಕುವಾಗ ಒಂದು ಸಮಸ್ಯೆ ಎದುರಾಗುತ್ತದೆ. ಇದ್ದದ್ದು ಸಾಕು ಎಂದು ಬದುಕುತ್ತಿರುವಾಗ\nನಮ್ಮ ಜೊತೆಗಿನ ಇನ್ನೊಬ್ಬ ಹೆಚ್ಚು ಗಳಿಸಲಾರಂಬಿಸಿದರೆ, ಅದನ್ನು ನೋಡಿ ನಮಗೆ ಕಿಚ್ಚು ಹುಟ್ಟಿಕೊಳ್ಳುತ್ತದೆ.\nನಮ್ಮ ಕೆಳಗಿನ ಮಟ್ಟದವರು, ನಮ್ಮ ಪಕ್ಕದ ಮನೆಯವರು ಯಾವುದೋ ಕಾರಣಕ್ಕೆ ಶ್ರೀಮಂತರಾದರೆ ನಮಗೆ\nಸಂಕಟ! ಇಲ್ಲಿ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: \"ಇನ್ನೊಬ್ಬರನ್ನು ಕಂಡು ಎಂದೂ ಕಿಚ್ಚು ಪಡಬೇಡ\" ಎಂದು. ಯಾರ್ಯಾರಿಗೆ\nಎಷ್ಟೆಷ್ಟು ಸಿಗಬೇಕೋ ಅಷ್ಟಷ್ಟೇ ಸಿಗುತ್ತದೆ. ನಾವು ಎಷ್ಟು ಕೌಶಲ್ಯವಂತರಾದರೂ ಕೂಡಾ ಭಗವಂತ\nಅನುಗ್ರಹಿಸದೇ ಇದ್ದರೆ ನಾವು ಮೇಲಕ್ಕೇಳಲು ಸಾಧ್ಯವಿಲ್ಲ. ಈ ಎಚ್ಚರವೇ \"ಯದೃಚ್ಛಾ ಲಾಭ ಸಂತುಷ್ಟ $”\n\nಇನ್ನು ಸಿದ್ಧಿ ಅಸಿದ್ಧಿಗಳು. ಉದಾಹರಣೆಗೆ ಧ್ಯಾನ: ಧ್ಯಾನದಲ್ಲಿ ಏಕಾಗ್ರತೆ ಪಡೆಯಲು ಆಗದೇ\nಇನ್ನೇನೋ ಕಾಣಿಸಿದರೆ. ಏನು ಕಾಣಿಸಿತೋ ಅದರಲ್ಲೇ ಭಗವಂತನನ್ನು ಕಾಣು. ಅದಕ್ಕಾಗಿ ತಲೆ\nಕೆಡಿಸಿಕೊಳ್ಳಬೇಡ. ಏಕಾಗ್ರತೆ ಸಾಧ್ಯವಾದರೆ ಭ್ರಮೆಗೊಳಗಾಗಬೇಡ. ಏಕೆಂದರೆ ಸಿದ್ಧಿ-ಅಸಿದ್ಧಿಗಳು ನಮ್ಮ\nಕೈಯಲ್ಲಿಲ್ಲ. ಅಸಿದ್ದಿಯೂ ಸಿದ್ಧಿಯ ಮೆಟ್ಟಿಲು. ಇಂತಹ ಮಾನಸಿಕ ಸಮತೋಲನ ಜೀವನದಲ್ಲಿ ಅತಿಮುಖ್ಯ.\nಇಂತಹ ಸ್ಥಿತಿಯಲ್ಲಿ ಕರ್ಮ ಎಂದೂ ಬಂಧಕವಾಗುವುದಿಲ್ಲ.",
  "4.23": "ಗತ ಸಂಗಸ್ಯ ಮುಕ್ತಸ್ಯ ಜ್ಞಾನ ಅವಸ್ಥಿತ ಚೇತಸಃ |\nಯಜ್ಞಾಯ ಆಚರತಃ ಕರ್ಮ ಸಮಗ್ರಮ್‌ ಪ್ರವಿಲೀಯತೇ -ಫಲದ ನಂಟು ತೊರೆದು, ದೇಹಾಭಿಮಾನ ತೊರೆದು,\nಭಗವಂತನ ಅರಿವಿನಲ್ಲೇ ಬಗೆನೆಟ್ಟು, ಪೂಜೆಯೆಂದು ಮಾಡುವವನ ಎಲ್ಲಾ ಕರ್ಮ ಲಯಗೊಳ್ಳುತ್ತದೆ.\n\nಈ ಶ್ಲೋಕದಲ್ಲಿ ಮೇಲೆ ಹೇಳಿದ ಎಲ್ಲಾ ವಿಷಯವನ್ನು ಉಪಸಂಹಾರ ರೂಪದಲ್ಲಿ ಭಗವಂತ ನಮ್ಮ\nಮುಂದಿಟ್ಟಿದ್ದಾನೆ.\n\nಫಲದ ಬಗ್ಗೆ ಅತಿಯಾದ ಆಸೆ ಇಟ್ಟುಕೊಳ್ಳಬೇಡ; ಅತಿಯಾದ ನಿರೀಕ್ಷೆ ಬೇಡ; ಕರ್ತವ್ಯನಿಷ್ಠೆ ಇರಲಿ;\nದೇಹಾಭಿಮಾನ, ಪರಿವಾರದ ಅಭಿಮಾನವನ್ನು ತೊರೆದು ನಿರ್ಲಿಪ್ತನಾಗಿ ಬದುಕಲು ಕಲಿ; ಮನಸ್ಸನ್ನು\nಜ್ಞಾನಸ್ವರೂಪನಾದ ಭಗವಂತ(ಚೇತಸ್ಸು)ನಲ್ಲಿ ನೆಲೆಗೊಳಿಸು. ಹೀಗೆ ಬದುಕಿದಾಗ ನಾವು ಮಾಡುವ\nಕರ್ಮವೆಲ್ಲವೂ ಯಜ್ಞವಾಗಿ ಯಜ್ಞ ನಾಮಕ ಭಗವಂತನನ್ನು ಸೇರುತ್ತದೆ ಹಾಗೂ ಜ್ಞಾನದ ಬೆಂಕಿಯಲ್ಲಿ ಕರ್ಮದ\nಕೊಳೆ ಸುಟ್ಟುಹೋಗುತ್ತದೆ.\n",
  "4.24": "ಬ್ರಹ್ಮ ಅರ್ಪಣಮ್‌ ಬ್ರಹ್ಮ ಹವಿಃ ಬ್ರಹ್ಮ ಅಗ್ನೌ ಬ್ರಹ್ಮಣಾ ಹುತಮ್‌ ।\n\nಬ್ರಹ್ಮ ಏವ ತೇನ ಗಂತವ್ಯಮ್‌ ಬ್ರಹ್ಮ ಕರ್ಮ ಸಮಾಧಿನಾ-ಅರ್ಪಣವೂ ಭಗವಂತ (ಭಗವಂತನಲ್ಲಿ ಅರ್ಪಣ].\nಅರ್ಪಿಸುವ ಹವಿಸ್ಸೂ ಭಗವಂತ[ಭಗವಂತನಾದ ಹವಿಸ್ಸು]. ಬೆಂಕಿಯ ರೂಪದಲ್ಲಿರುವ ಭಗವಂತನಲ್ಲಿ\n[ಭಗವದಧೀನವಾದ ಬೆಂಕಿಯಲ್ಲಿ] ಭಗವಂತನಿಂದಲೇ ಹೋಮಮಾಡಿತು. ಬಗೆಯ ಏಕಾಗ್ರತೆಯ ಜತೆಗೆ\nಕರ್ಮದ ವ್ಯಗ್ರತೆಯೂ ಭಗವಂತನೇ [ಭಗವಂತನ ಅಧೀನವಾದದ್ದು]\n\nಅಭಿಮಾನ ತ್ಯಾಗದಿಂದ ಜ್ಞಾನದ ಸ್ಥಿತಿಯಲ್ಲಿ ಕರ್ಮ ಮಾಡಿದರೆ ಹೇಗಿರುತ್ತದೆ ಎನ್ನುವುದಕ್ಕೆ ಉತ್ತರ\n\"ಬ್ರಹ್ಮಾರ್ಪಣಂ ಬ್ರಹ್ಮಹವಿಃ\" . ಇಲ್ಲಿ ಅರ್ಪಣ ಅನ್ನುವುದನ್ನು ಈ ರೀತಿ ಅರ್ಥ ಮಾಡಿಕೊಳ್ಳಬಹುದು. ನಾವು\nಒಂದು ಹವಿಸ್ಸನ್ನು ಅಗ್ನಿಯಲ್ಲಿ ಭಗವಂತನಿಗೆ ಅರ್ಪಣೆ ಮಾಡುತ್ತೇವೆ- ಇದು ಅರ್ಪಣೆ. ಒಬ್ಬ ಹಸಿದವನಿಗೆ ಅನ್ನ\nನೀಡುತ್ತೇವೆ-ಇದು ಅರ್ಪಣೆ. ಒಬ್ಬ ಯೋಗ್ಯ ವರನಿಗೆ ಕನ್ಯಾದಾನ ಮಾಡುತ್ತೇವೆ-ಇದು ಅರ್ಪಣೆ. ಒಬ್ಬ ಹಣದ\nಸಮಸ್ಯೆಯಲ್ಲಿದ್ದಾಗ ಆತನಿಗೆ ಸಹಾಯ ಮಾಡುತ್ತೇವೆ-ಇದು ಅರ್ಪಣೆ. ಇಲ್ಲಿ ಕೊಡುವವನೂ ಆ ಭಗವಂತ,\nತೆಗೆದುಕೊಳ್ಳುವವನ ಒಳಗಿದ್ದು ಸ್ವೀಕರಿಸುವವನೂ ಅವನೇ. ಎಲ್ಲವೂ ಭಗವಂತನ ಇಚ್ಛೆಯಂತೆ ನಡೆಯುತ್ತದೆ.\nಹವಿಸ್ಸು ಅಂದರೆ ಕೊಡುವ ವಸ್ತು. ಅರ್ಪಣ-ಕೊಡುವ ಕ್ರಿಯೆ. ಯಾವ ವಸ್ತು ಕೂಡಾ ಹವಿಸ್ಸಾಗಬಹುದು. ದಾನದ\nದ್ರವ್ಯ-ಹವಿಸ್ಸು, ಯಜ್ಞದಲ್ಲಿ ಅಗ್ನಿ ಮುಖೇನ ಅರ್ಪಿಸುವ ದ್ರವ್ಯ-ಹವಿಸ್ಸು. ನಾವು ಹುಟ್ಟುವಾಗ ಏನನ್ನೂ\nತೆಗೆದುಕೊಂಡು ಬಂದಿಲ್ಲ, ಎಲ್ಲವನ್ನೂ ಈ ಪ್ರಕೃತಿಯಿಂದ ಪಡೆದಿರುವುದು ಅಂದಮೇಲೆ, ನಾವು ಕೊಡುವ\nಹವಿಸ್ಸು ಕೂಡಾ ಆ ಭಗವಂತನ ಅಧೀನ. ಇಲ್ಲಿ 'ನನ್ನದು' ಎನ್ನುವುದು ಹಾಸ್ಯಾಸ್ಪದ.\n\nಅಗ್ನಿ ಮುಖೇನ ನಾವು ದ್ರವ್ಯವನ್ನು ಅರ್ಪಿಸುತ್ತೇವೆ. ಇಲ್ಲಿ ಅಗ್ನಿ ಎಂದರೆ ಬರಿಯ ಜಡವಾದ ಬೆಂಕಿ ಅಲ್ಲ.\nಸಂಸ್ಕೃತದಲ್ಲಿ ಅಗ್ನಿ ಎಂದರೆ ಅಗ್ನಿಯ ಅಭಿಮಾನಿ ದೇವತೆ, ಅದು ಚೇತನ. ಈ ಕಾರಣಕ್ಕಾಗಿ ಅಗ್ನಿಯನ್ನು\nಸಾಕ್ಷಿಯಾಗಿ ಬಳಸುತ್ತಾರೆ (ಉದಾ: ಅಗ್ನಿಸಾಕ್ಷಿಯಾಗಿ ಮದುವೆಯಾಗುವುದು). ಜಡವನ್ನು ಎಂದೂ ಸಾಕ್ಷಿಯಾಗಿ\nಬಳಸಲು ಬರುವುದಿಲ್ಲ. ಈ ಅಗ್ನಿದೇವತೆಯ ಒಳಗೆ ತಾರಕ ಶಕ್ತಿಯಾಗಿ ಆ ಭಗವಂತನಿದ್ದಾನೆ. ಇಲ್ಲಿ\nಕೊಡುವುದು, ಕೊಡತಕ್ಕದ್ದು, ಕೊಡುವ ಕ್ರಿಯೆ, ಕೊಟ್ಟ ಸ್ಥಳ-ಎಲ್ಲವೂ ಭಗವಂತನ ಅಧೀನ. ಎಲ್ಲಾ ಕ್ರಿಯೆಯಲ್ಲಿ\nಭಗವಂತನ ಸನ್ನಿಧಾನವಿದೆ. ಕೊಡತಕ್ಕ ವಸ್ತುವಿನಲ್ಲಿ. ಆತನ ಸನ್ನಿಧಾನವಿರುವುದರಿಂದ ಅದು\nಉಪಯುಕ್ತವಾಗಿರುತ್ತದೆ. ಜ್ಞಾನರೂಪನಾದ ಭಗವಂತ ಅಗ್ನಿಯಲ್ಲಿ ಸನ್ನಿಹಿತನಾಗಿ ಭಕ್ತಿ ರೂಪದ ಆಹುತಿಯನ್ನು\nಸ್ವೀಕರಿಸುತ್ತಾನೆ. ಈ ಅನುಸಂಧಾನದಿಂದ ನಮ್ಮ ಕ್ರಿಯೆ ನಡೆದರೆ, ನಾವು ಭಗವಂತನ ಆರಾಧನೆ ಮಾಡಿದಾಗ\n\"ಬ್ರಹ್ಮೈವ ತೇನ ಗಂತವ್ಯಂ\"”-ಹೋಗಿ ಸೇರುವುದೂ ಭಗವಂತನನ್ನೇ. ಏಕೆಂದರೆ \"ಬ್ರಹ್ಮಕರ್ಮಸಮಾಧಿನಾ\" -\nಎಲ್ಲವೂ ಸರ್ವಸಮರ್ಥನಾದ ಭಗವಂತನ ಅಧೀನ.\n\nಇಲ್ಲಿ ಬ್ರಹ್ಮಾರ್ಪಣ ಎಂದರೆ ಎಲ್ಲಾ ಕ್ರಿಯೆಯೂ ಭಗವಂತನಿಗೆ ಎಂದರ್ಥ. ಪ್ರಪಂಚದಲ್ಲಿರುವ ಎಲ್ಲಾ ವಸ್ತುವನ್ನು\nಸೃಷ್ಟಿಸಿದ್ದು ಆ ಭಗವಂತ. ಪ್ರಕೃತಿಯಲ್ಲಿ ಸೃಷ್ಟಿಯಾಗಿರುವುದನ್ನು ನಾವು ಉಪಯೋಗಿಸುತ್ತೇವೆ ಅಷ್ಟೇ. ಅಗ್ನಿ\nಭಗವಂತನ ಅಧೀನವಾಗಿ ಕಾರ್ಯ ನಿರ್ವಹಿಸುತ್ತಾನೆ. 'ನಾವು ಮಾಡುವ ಕ್ರಿಯೆ ಆ ಭಗವಂತನ ಪ್ರೇರಣೆ. ನಾವು\nಮಾಡುವ ಎಲ್ಲಾ ಕರ್ಮವೂ ಬ್ರಹ್ಮಕರ್ಮ. ಅದು ಭಗವಂತನ ಪೂಜಾರೂಪವಾದ ಕರ್ಮ'- ಇದು ಕರ್ಮದ ಬಗ್ಗೆ\nನಮಗಿರಬೇಕಾದ ಜ್ಞಾನ. ನಾವು ಮಾಡುವ ಕರ್ಮದಲ್ಲಿ ನಮ್ಮ ಸ್ವಾರ್ಥ ಇರಕೂಡದು. ಅದು ಭಗವಂತನ ಪೂಜಾ\nರೂಪವಾಗಿರಬೇಕು. ಯಜ್ಞ ಎಂದರೆ ಅಗ್ನಿ ಮುಖೇನ ಮಾಡುವ ಕ್ರಿಯೆ ಮಾತ್ರ ಅಲ್ಲ. ನಮ್ಮ ಬದುಕನ್ನು\n\nಭಗವನ್ಮಯ ಮಾಡಿಕೊಂಡಾಗ ನಮ್ಮ ಜೀವನದ ಎಲ್ಲಾ ನಡೆಯೂ ಯಜ್ಞವಾಗಿಬಿಡುತ್ತದೆ. ನಮ್ಮ ಬದುಕು\nಭಗವಂತನ ಚಿಂತನೆಗೆ ಮೀಸಲಾದಾಗ ನಮ್ಮ ಬದುಕೇ ಒಂದು ಮಹಾಯಜ್ಞ. ಭಗವಂತನ ಚಿಂತನೆ ಇಲ್ಲದೆ\nಸ್ವಾರ್ಥದಿಂದ ಮಾಡುವ ಅಗ್ನಿ ಮುಖೇನವಾದ ಯಜ್ಞ ಕೇವಲ ವ್ಯಾಪಾರ. ಪೌರೋಹಿತ್ಯ ಕೂಡಾ ಹೀಗೆ. ತಿಳಿದು\nಮಾಡಿದಾಗ ಮಾತ್ರ ಅದು ನಿಜವಾದ ಪೌರೋಹಿತ್ಯ, ಇಲ್ಲದಿದ್ದರೆ ಅದು ಕೇವಲ ದುಡ್ಡಿಗಾಗಿ ಮಾಡುವ ದಂದೆ!\n\nಈ ತನಕ ಕೃಷ್ಣ ಕರ್ಮದ ಪ್ರಭೇದದ ಬಗ್ಗೆ ಹೇಳಿದ. ದೇವರ ಪೂಜಾರೂಪವಾಗಿ ಮಾಡುವ ಪ್ರತಿಯೊಂದು\nಕಾರ್ಯ ಕೂಡಾ ಯಜ್ಞ ಎನ್ನುವ ವಿಚಾರ ವಿಶ್ಲೇಷಣೆ ಮಾಡಿದ. ಮುಂದೆ ಯಜ್ಞದ ಬಗ್ಗೆ ವ್ಯಾಪಕವಾದ ಅರ್ಥವನ್ನು\nಕೃಷ್ಣ ವಿವರಿಸುತ್ತಾನೆ. ಹಿಂದೆ ಹೇಳಿದಂತೆ ಅಗ್ನಿಮುಖದಲ್ಲಿ ಮಾಡುವ ಪೂಜೆ ಮಾತ್ರ ಯಜ್ಞವಲ್ಲ. ಕೊಡುವಿಕೆ,\nಪೂಜೆಯಂತಹ ಒಳ್ಳೆಯ ಕಾರ್ಯಕ್ಕೆ ಒಂದು ಕಡೆ ಸೇರುವಿಕೆ(ಸಂಗತೀಕರಣ), ಜ್ಞಾನದಾನ, ಅನ್ನದಾನ, ನಮ್ಮಲ್ಲಿ\nಹೆಚ್ಚಿಗೆ ಇರುವುದನ್ನು ಇಲ್ಲದವರಿಗೆ ಹಂಚಿ ಬದುಕುವುದು, ಎಲ್ಲವೂ ಒಂದು ಯಜ್ಞವೇ. . ಮುಂದಿನ ಶ್ಲೋಕಗಳಲ್ಲಿ\nಯಜ್ಞದ ವಿಶ್ವತೋಮುಖ ಚಿತ್ರವನ್ನು ಕೃಷ್ಣ ನಮಗೆ ನೀಡುತ್ತಾನೆ.\n\nಸಾಮಾನ್ಯವಾಗಿ ಯಜ್ಞದಲ್ಲಿ ಎರಡು ವಿಧ. ಒಂದು ಅಂತರಂಗ ಯಜ್ಞ ಇನ್ನೊಂದು ಬಾಹ್ಯಯಜ್ಞ. ಅಂತರಂಗದಲ್ಲಿ\nಭಗವಂತನ ನಿರಂತರ ಪೂಜೇ(ದೇವಪೂಜಾ); . ಚಿತ್ತ-ಮನಸ್ಸು... ಭಗವಂತನ ಜೊತೆಗೆ\nಸೇರುವುದು(ಸಂಗತೀಕರಣ) ಮತ್ತು ನಮ್ಮನ್ನು ನಾವು ಭಗವಂತನಿಗೆ ಅರ್ಪಿಸಿಕೊಳ್ಳುವುದು-ಇದು\nಪರಿಪೂರ್ಣವಾದ ಮಾನಸ ಯಜ್ಞ. ಇನ್ನೊಂದು ರೀತಿಯಲ್ಲಿ ಯಜ್ಞದಲ್ಲಿ ಎರಡು ಬಗೆ: ಜ್ಞಾನಪ್ರದವಾದ ಯಜ್ಞ\nಹಾಗೂ ಕರ್ಮಪ್ರದವಾದ ಯಜ್ಞ. ಈ ಎಲ್ಲಾ ವಿವರಣೆಯನ್ನು ಮುಂದಿನ ಶ್ಲೋಕಗಳಲ್ಲಿ ಕೃಷ್ಣ ವಿವರಿಸಿದ್ದಾನೆ.\n\nದೈವಮೇವಾಪರೇ ಯಜ್ಞಂ ಯೋಗಿನಃ ಪರ್ಯುಪಾಸತೇ",
  "4.25": "ದೈವಮ್‌ ಏವ ಅಪರೇ ಯಜ್ಞಮ್‌ ಯೋಗಿನಃ ಪರ್ಯುಪಾಸತೇ |\n\nಬ್ರಹ್ಮ ಅಗ್ನೌ ಅಪರೇ ಯಜ್ಞಮ್‌ ಯಜ್ಞೇನ ಏವ ಉಪಜುಹ್ವತಿ-ಕೆಲವು ಸಾಧಕರು ಭಗವದುಪಾಸನೆಯೆಂಬ\nಮಾನಸ ಯಜ್ಞವನ್ನು ಆಚರಿಸುತ್ತಾರೆ.[ಭಗವಂತನನ್ನೇ ಯಜ್ಞ ರೂಪನೆಂದು ಪೂಜಿಸುತ್ತಾರೆ.] ಕೆಲವರು ಬೆಂಕಿಯ\nರೂಪದ ಭಗವಂತನಲ್ಲಿ ಹೋಮಿಸುವ ಮೂಲಕ ಬಾಹ್ಯ ಯಜ್ಞದಿಂದ ಯಜ್ಞ ನಾಮಕ ಭಗವಂತನನ್ನು\nಪೂಜಿಸುತ್ತಾರೆ.[ಯಜ್ಞನಾಮಕ ಭಗವಂತನಿಂದಲೇ ಬಾಹ್ಯ ಯಜ್ಞವನ್ನು ಆಚರಿಸುತ್ತಾರೆ].\n\nಭಗವಂತನ ಉಪಾಸನೆಯ ಮಾರ್ಗದಲ್ಲಿ ಸಾಗುವ ಕೆಲವು ಯೋಗಿಗಳು(ಸಾಧಕರು) ದೈವವನ್ನೇ ಯಜ್ಞವಾಗಿ\nಉಪಾಸನೆ ಮಾಡುತ್ತಾರೆ. ಅಂದರೆ ನಿರಂತರ ಅಂತರಂಗದಲ್ಲಿ ಭಗವಂತನ ಉಪಾಸನೆಯೇ ಅವರ ಯಜ್ಞ.\nಇದಕ್ಕೆ ಯಾವ ಬಾಹ್ಯ ಪರಿಕರ ಬೇಡ. ಇದು ಧ್ಯಾನ ರೂಪ ಯಜ್ಞ. ಈ ರೀತಿ ಬಾಹ್ಯ ಪರಿಕರಗಳಿಲ್ಲದೇ ಮಾಡುವ\nಯಜ್ಞ ಅತ್ಯಂತ ಶ್ರೇಷ್ಠ ಯಜ್ಞ. ಇದು ಸಾಮಾನ್ಯವಾಗಿ ಅತ್ಯಂತ ಎತ್ತರಕ್ಕೇರಿದ ಸಾಧಕರು ಮಾಡಬಲ್ಲ ಯಜ್ಞ.\nಎಲ್ಲಾ ಬಾಹ್ಯ ಪರಿಕರಗಳನ್ನು ಬಿಟ್ಟು ಮಾನಸ ಪರಿಗ್ರಹದಿಂದ ಮಾಡತಕ್ಕ ಜ್ಞಾನಪ್ರಧಾನವಾದ ಯಜ್ಞವಿದು.\n\nಇನ್ನೊಂದು ಪ್ರಕಾರದ ಯಜ್ಞ ಅಗ್ನಿ ಮುಖದಲ್ಲಿ ಮಾಡತಕ್ಕ ಕರ್ಮ ಪ್ರಧಾನವಾದ ಯಜ್ಞ. ಇದನ್ನು ಸಾಮಾನ್ಯ\nಮಾನವರು ಅನುಸರಿಸುತ್ತಾರೆ. ಭಗವಂತನ ಸನ್ನಿಧಾನವಿರುವ ಅಗ್ನಿಯ ಮುಖದಲ್ಲಿ ಭಗವಂತನಿಗೆ ಅರ್ಪಣೆ\nಮಾಡುವ ಆರಾಧನೆ. ಇದು ಬಾಹ್ಯ ಯಜ್ಞ. ಇದು ಬಹಳ ಮುಖ್ಯವಾದದ್ದು. ವೇದದಲ್ಲಿ ಭಗವಂತನ ಆರಾಧನೆಗೆ\nಅತ್ಯಂತ ಮುಖ್ಯವಾದ ಪ್ರತೀಕ ಅಗ್ನಿ ಎನ್ನುತ್ತಾರೆ. ಅಗ್ನಿ ಎಂದೂ ಅಪವಿತ್ರವಲ್ಲ. ಅಗ್ನಿ ಸ್ಪರ್ಶದಿಂದ ಅಪವಿತ್ರ\nಕೂಡಾ ಪವಿತ್ರವಾಗುತ್ತದೆ. ನಮಗೆ ಭಗವಂತನಿಗೆ ಏನನ್ನಾದರೂ ತಿನ್ನಿಸಬೇಕು ಎನ್ನುವ ಅಭಿಲಾಷೆ ಇದ್ದರೆ\nಅದನ್ನು ಕೇವಲ ಅಗ್ನಿ ಮುಖೇನ ಮಾಡಬಹುದು. ನಮ್ಮ ಕಣ್ಣ ಮುಂದೆ ಇರುವ ಎಲ್ಲಾ ಪ್ರತೀಕಗಳಲ್ಲಿ ಅಗ್ನಿ\nಅತ್ಯಂತ ಶ್ರೇಷ್ಠ ಎನ್ನುವುದು ವೇದ ಕಾಲದ ಖುಷಿಗಳ ತೀರ್ಮಾನ. ಸುಡುವ ಅಗ್ನಿಯಲ್ಲಿ ಅಗ್ನಿದೇವ, ಅವನೊಳಗೆ\nಪ್ರಾಣ, ಪ್ರಾಣನೊಳಗೆ ಭಗವಂತ. ಈ ಅನುಸಂಧಾನದಲ್ಲಿ ಯಜ್ಞ ನಾಮಕ ಭಗವಂತನನ್ನು, ಯಜ್ಞದಿಂದ, ಜ್ಞಾನ\nಭಕ್ತಿ ವೈರಾಗ್ಯದಿಂದ ಕೂಡಿದ ಉತ್ಕೃಷ್ಟವಾದ ಆಹ್ವಾನದಿಂದ ಆರಾಧನೆ.",
  "4.26": "ಶ್ರೋತ್ರಾ ಆದೀನಿ ಇಂದ್ರಿಯಾಣಿ ಅನ್ಯೇ ಸಂಯಮ ಅಗ್ನಿಷು ಜುಹ್ವತಿ |\nಶಬ್ದ ಆದೀನ್‌ ವಿಷಯಾನ್‌ ಅನ್ಯ ಇಂದ್ರಿಯ ಅಗ್ನಿಷು ಜುಹ್ವತಿ-ಕೆಲವರು ಕಿವಿ ಮೊದಲಾದ ಇಂದ್ರಿಯಗಳನ್ನು\nಅಂಕೆಯ ಬೆಂಕಿಯಲ್ಲಿ ಹೋಮಿಸುತ್ತಾರೆ. ಕೆಲವರು ಶಬ್ದ ಮೊದಲಾದ ವಿಷಯಗಳನ್ನು ಇಂದ್ರಿಯಗಳ ಬೆಂಕಿಯಲ್ಲಿ\nಹೋಮಿಸುತ್ತಾರೆ.\n\nಒಬ್ಬ ಸಾಧಕನಲ್ಲಿರಬೇಕಾದ ವಿಶಿಷ್ಟ ಸಾಧನೆ ಕೂಡಾ ಒಂದು ಯಜ್ಞ. ಇಂದ್ರಿಯವೆಂಬ ಹವಿಸ್ಸನ್ನು 'ನಿಗ್ರಹ'\nಎನ್ನುವ ಬೆಂಕಿಯಲ್ಲಿ ಆಹುತಿಗೊಳಿಸುವುದು ಒಂದು ಯಜ್ಞ. ಕೆಟ್ಟದ್ದನ್ನು ಕೇಳುವುದಿಲ್ಲ, ಕೆಟ್ಟದ್ದನ್ನು ಆಡುವುದಿಲ್ಲ,\nಕೆಟ್ಟದ್ದನ್ನು ನೋಡುವುದಿಲ್ಲ, ಎನ್ನುವ ದೃಢ ನಿಶ್ಚಯದಿಂದ, ಇಂದ್ರಿಯ ಸಂಯಮದಿಂದ ಇಂದ್ರಿಯ ಚಾಪಲವನ್ನು\nಹೋಮಿಸು. ಇದು ಇಂದ್ರಿಯ ಚಾಪಲವನ್ನು ಗೆಲ್ಲುವ ಪ್ರಕ್ರಿಯೆ. ಸಂಯಮ ಎನ್ನುವ ಅಗ್ನಿಯಲ್ಲಿ ಇಂದ್ರಿಯ\nಚಾಪಲವೆಂಬ ಹವಿಸ್ಸನ್ನು ಹೋಮಿಸಿ, ಭಗವಂತನನ್ನು ಆರಾಧಿಸುವುದು. ಭಗವಂತ ಪ್ರಸನ್ನನಾಗಲಿ, ಅದರ\nಮೂಲಕ ನನ್ನನ್ನು ಸಾಧನೆಯ ದಾರಿಯಲ್ಲಿ ಮುನ್ನೆಡೆಸಲಿ ಎನ್ನುವ ಅನುಸಂಧಾನದಲ್ಲಿ ಮಾಡುವ ಯಜ್ಞವಿದು.\nಇನ್ನು ಒಳ್ಳೆಯ ಸಂಗತಿಗಳನ್ನು ಇಂದ್ರಿಯಗಳಲ್ಲಿ ಹೋಮಿಸುವುದೂ ಒಂದು ಯಜ್ಞ. ಕಿವಿ ಎನ್ನುವ ಅಗ್ನಿ ಕುಂಡದಲ್ಲಿ\nಭಗವಂತನ ಗುಣಗಾನವೆಂಬ ಹವಿಸ್ಸನ್ನು ಹಾಕುವುದು, ಕಣ್ಣು ಎನ್ನುವ ಅಗ್ನಿ ಕುಂಡದಲ್ಲಿ ಭಗವಂತನ ಪ್ರತೀಕ\nಎನ್ನುವ ಹವಿಸ್ಸನ್ನು ಹಾಕುವುದು, ಮೂಗು ಎನ್ನುವ ಅಗ್ನಿ ಕುಂಡದಲ್ಲಿ ಭಗವಂತನಿಗೆ ಅರ್ಪಿತವಾದ ತುಳಸಿ, ಗಂಧ\nರೂಪದ ಹವಿಸ್ಸನ್ನು ಹಾಕುವುದು. ಹೀಗೆ ಇಂದ್ರಿಯ ವಿಷಯಗಳನ್ನು ಸ್ವೀಕರಿಸುವುದೂ ಒಂದು ಯಜ್ಞವಾಗುತ್ತದೆ.\nಇಂದ್ರಿಯ ನಿಗ್ರಹದಂತೆ ಇಂದ್ರಿಯ ಗ್ರಹಣ ಕೂಡಾ ಒಂದು ಯಜ್ಞ. ಭಗವಂತನ ಚಿಂತನೆಗೆ ಪೂರಕವಾದ\nವಿಷಯವನ್ನು ಗ್ರಹಣ ಮಾಡು ಮತ್ತು ಅಲ್ಲದ ವಿಷಯವನ್ನು ತ್ಯಾಗ ಮಾಡು-ಇದು ಸಾಧನೆಯ ಹಾದಿಯಲ್ಲಿ\nಪ್ರಮುಖ ಹೆಜ್ಜೆ.",
  "4.27": "ಸರ್ವಾಣಿ ಇಂದ್ರಿಯ ಕರ್ಮಾಣಿ ಪ್ರಾಣಕರ್ಮಾಣಿ ಚ ಅಪರೇ |\nಆತ್ಮ ಸಂಯಮ ಯೋಗ ಅಗ್ನ್‌ ಜುಹ್ವತಿ ಜ್ಞಾನದೀಪಿತೇ-ಕೆಲವರು ಎಲ್ಲಾ ಇಂದ್ರಿಯ ಕ್ರಿಯೆಗಳನ್ನೂ,\nಪ್ರಾಣವಾಯುವಿನ ಕ್ರಿಯೆಗಳನ್ನೂ ತಿಳಿವಿನಿಂದ ತಿಳಿಗೊಂಡ ಆತ್ಮನಿಗ್ರಹದ ಸಾಧನೆಯೆಂಬ ಬೆಂಕಿಯಲ್ಲಿ\nಹೋಮಿಸುತ್ತಾರೆ.\n\nನಮ್ಮ ದೇಹದಲ್ಲಿ ಜ್ಞಾನೇಂದ್ರಿಯ ಹಾಗೂ ಕರ್ಮೇಂದ್ರಿಯದಿಂದ ನಿರಂತರ ಕ್ರಿಯೆ ನಡೆಯುತ್ತಿರುತ್ತದೆ. ಇದಲ್ಲದೆ\nಪ್ರಾಣಶಕ್ತಿಯಿಂದ ಆಗುವ ಕ್ರಿಯೆಗಳು ಅನೇಕ (ಉದಾ: ಉಸಿರಾಟ, ಬಲ, ಸಂತಾನಶಕ್ತಿ, ಸಂತೋಷ ಅಥವಾ\nದುಃಖವಾದಾಗ ಕಣ್ಣೀರು ಇತ್ಯಾದಿ). ಮನೋನಿಗ್ರಹ ಎನ್ನುವ ಅಗ್ನಿಯಲ್ಲಿ ಈ ಜ್ಞಾನೇಂದ್ರಿಯ, ಕರ್ಮೇಂದ್ರಿಯ\nಮತ್ತು ಪ್ರಾಣಶಕ್ತಿಯಿಂದ ಆಗುವ ಕ್ರಿಯೆಯನ್ನು ಹೋಮಿಸುವುದು(ಹಿಡಿತ) ಒಂದು ಯಜ್ಞ. ಇದು ಹಠಕ್ಕೋಸ್ಕರ\nಅಲ್ಲ, ಯಜ್ಞ ರೂಪವಾಗಿ ಭಗವಂತನ ಪೂಜಾರೂಪವಾಗಿ. ಇದು ಭಗವಂತನ ಅರಿವಿನಿಂದ ಬೆಳಗುವ ಆತ್ಮ\nಸಂಯಮ. ಭಗವಂತನ ಅರಿವಿಗೋಸ್ಕರ ಮಾಡಿದ ಆತ್ಮಸಂಯಮ; ಭಗವಂತನ ಅರಿವಿನೆಡೆಗೆ\nಕೊಂಡೊಯ್ಯುವ ಜ್ಞಾನಪೂರ್ವಕ ಸಂಯಮ, ಆವೇಶವಲ್ಲ.\n\nಯಜ್ಞಗಳ ವೈವಿದ್ಯವನ್ನು ಹೇಳುತ್ತಾ ಮುಂದುವರಿದು ಕೃಷ್ಣ ಯಜ್ಞದ ಒಂದು ಪಟ್ಟಿಯನ್ನು ನಮ್ಮ ಮುಂದಿಡುತ್ತಾನೆ:",
  "4.28": "ದ್ರವ್ಯ ಯಜ್ಞಾಃ ತಪಃ ಯಜ್ಞಾಃ ಯೋಗ ಯಜ್ಞಾಃ ತಥಾ ಅಪರೇ |\n\nಸ್ವಾಧ್ಯಾಯ ಜ್ಞಾನ ಯಜ್ಞಾಃ ಚ ಯತಯಃ ಸಂಶಿತ ವ್ರತಾಃ -ಕೆಲವರು ಸೊತ್ತುಗಳನ್ನು ಹೋಮಿಸುವವರು.\nಕೆಲವರು ತಪಸ್ಸನ್ನೇ ಭಗವಂತನಲ್ಲಿ ಹೋಮಿಸುವವರು. ಕರ್ಮ ಸಾಧನೆಯೇ ಕೆಲವರ ಯಜ್ಞ. ಚುರುಕು ನಿಷ್ಠೆಯ\nಪ್ರಯತ್ನ ಶೀಲರಾದ ಕೆಲವರಿಗೆ ವೇದಾಧ್ಯಯನ, ಭಗವಂತನ ಅರಿವೇ ಯಜ್ಞ.\n\nದ್ರವ್ಯಯಜ್ಞ: ಕೆಲವರು... ದ್ರವ್ಯದ ಮೂಲಕ ಭಗವಂತನನ್ನು ಆರಾಧನೆ ಮಾಡುತ್ತಾರೆ. ಇದು ಅಗ್ನಿ\nಮುಖೇನವಿರಬಹುದು, ಧನದಾನ, ಅನ್ನದಾನ, ಕನ್ಯಾದಾನ ಇತ್ಯಾದಿ ದಾನಗಳ ಮುಖೇನ ಇರಬಹುದು.\nಯೋಗ್ಯನಾದವನಿಗೆ, ಯೋಗ್ಯ ಕಾಲದಲ್ಲಿ, ಯೋಗ್ಯವಾದುದನ್ನು, ಅವರೊಳಗಿರುವ ಭಗವಂತ ಪ್ರೀತನಾಗಲಿ\nಎಂದು ಕೊಡುವುದು ದ್ರವ್ಯ ಯಜ್ಞ.\n\nತಪೋಯಜ್ಜ: ಇದಕ್ಕೆ ಎರಡು ಮುಖ. ಒಂದು ಬಾಹ್ಯ ಇನ್ನೊಂದು ಅಂತರಂಗ. ಒಂದು ನಿರಂತರ ಧ್ಯಾನ, ಅದಕ್ಕೆ\nಬಾಹ್ಯ... ಪರಿಕರಗಳ ಅಗತ್ಯವಿಲ್ಲ... ಎರಡನೇಯದು... ಭಗವಂತನ ಚಿಂತನೆಗೆ. ಬೇಕಾದ\n\nಆತ್ಮಸಂಯಮ-ಇದನ್ನು ತಪಸ್ಸು ಎನ್ನುತ್ತಾರೆ... ಉದಾಹರಣೆಗೆ ಬ್ರಹ್ಮಚರ್ಯಪಾಲನೆ,\nವೃತಾನುಷ್ಠಾನ, ಇತ್ಯಾದಿ.\n\nಯೋಗಯಜ್ಞ: ಅಂದರೆ ವಿಧವಿಧವಾದ ಕರ್ಮಯೋಗವನ್ನು ಭಗವಂತನ ಪ್ರೀತ್ಯರ್ಥ ಅನುಷ್ಠಾನ ಮಾಡುವುದು.\nಇದು ಬಾಹ್ಯ ಕರ್ಮಗಳ ಮೂಲಕ ಭಗವಂತನ ಆರಾಧನೆ. ಉದಾಹರಣೆಗೆ: ದೇವರಿಗೆ 108 ಪ್ರದಕ್ಷಿಣೆ, ಅರ್ಚನೆ ,\nಇತ್ಯಾದಿ. ಇದಲ್ಲದೆ ಯೋಗ ಶಾಸ್ತ್ರದಲ್ಲಿ ಹೇಳಿರುವ ಯಮನಿಯಮನ ಪಾಲನೆ.\n\nಸ್ವಾಧ್ಯಾಯ ಜ್ಞಾನಯಜ್ಞ: ಇದು ಭಗವಂತನಿಗೆ ಅತ್ಯಂತ ಪ್ರಿಯವಾದ ಯಜ್ಞ. ಇಲ್ಲಿ ಸ್ವಾಧ್ಯಾಯ ಎನ್ನುವುದಕ್ಕೆ\nಅನೇಕ ಅರ್ಥಗಳಿವೆ. ತನಗೆ ಸಂಬಂಧಪಟ್ಟದ್ದನ್ನು, ತಾನು ಓದಬೇಕಾದುದನ್ನು ಓದುವುದು. ತನ್ನ ಶಾಖೆಯ\nವೇದಾಧ್ಯಯನ; ಎಲ್ಲಾ ಕಡೆ ಸ್ವತಂತ್ರನಾಗಿರುವ ಸರ್ವೋತ್ತಮನಾದ ಭಗವಂತನ ಗುಣವನ್ನು ಅಧ್ಯಯನ\nಮೂಲಕ ಎಲ್ಲಾ ಗ್ರಂಥಗಳಲ್ಲಿ ಕಂಡುಕೊಳ್ಳುವುದು ಸ್ವಾಧ್ಯಾಯ. ಈ ಕಾಲದಲ್ಲಿ ಶಾಸ್ತ್ರದ ರಹಸ್ಯವನ್ನು ತಿಳಿದವರು\nಸಿಗುವುದು ತುಂಬಾ ವಿರಳ. ಅಂತಹ ಸಂದರ್ಭದಲ್ಲಿ ಕಾಲವನ್ನು ವ್ಯರ್ಥ ಮಾಡದೇ, ಭಗವಂತ ಎಷ್ಟು ಬುದ್ಧಿ\nಕೊಟ್ಟಿ ದ್ದಾನೋ ಅಷ್ಟ ನ್ನು ಬಳಸಿ ಸ್ವಂತ ಎಷ್ಟು ಸಾಧ್ಯವೋ ಅಷ್ಟ ನ್ನು ಅಧ್ಯಯನ ಮಾಡುವುದೂ ಸ್ವಾಧ್ಯಾಯ. ಈ\nಎಲ್ಲಾ ಸ್ವಾಧ್ಯಾಯ ನಮ್ಮ ಜ್ಞಾನದ ಬೆಳವಣಿಗೆಗೆ ಪೋಷಕವಾದದ್ದು. ನಾವು ತಿಳಿಯುವುದು, ತಿಳಿದದ್ದನ್ನು\nಇನ್ನೊಬ್ಬರಿಗೆ ಹಂಚುವುದು ಭಗವಂತನಿಗೆ ಅತ್ಯಂತ ಪ್ರಿಯ. ಇನ್ನೊಬ್ಬರಿಗೆ ಹಂಚುವುದರಿಂದ ಹೆಚ್ಚಾಗುವ\nಏಕಮೇವ ಸಂಪತ್ತು ಎಂದರೆ ಅದು ಜ್ಞಾನ. ಜ್ಞಾನಯಜ್ಞ ಮಾಡಬೇಕಾದರೆ ನಾವು ಯತಿಗಳಾಗಬೇಕು. ಇಲ್ಲಿ\nಯತಿ ಎಂದರೆ ಸನ್ಯಾಸಿ ಅಲ್ಲ. ಯತಿ ಅಂದರೆ ನಿರಂತರ ಪ್ರಯತ್ನಶೀಲ. ಸಾಧನೆ ಜೊತೆಗೆ ಹರಿತವಾದ ವೃತ\nಕೂಡಾ ಅಗತ್ಯ. ಅಂದರೆ ಸ್ವಚ್ಛವಾದ ಪ್ರಾಮಾಣಿಕವಾದ ಬದುಕು. ಇದಿಲ್ಲದೇ ಮಾಡುವ ಯಾವ ಕರ್ಮ ಕೂಡಾ\nಯಜ್ಞವಾಗುವುದಿಲ್ಲ. ಅಧ್ಯಾತ್ಮದ ದಾರಿಯಲ್ಲಿ ಮುಂದೆ ಸಾಗಲು ಛಲ ಅಗತ್ಯ.\n",
  "4.29": "ಅಪಾನೇ ಜುಹ್ವತಿ ಪ್ರಾಣಮ್‌ ಪ್ರಾಣೇ ಅಪಾನಮ್‌ ತಥಾ ಅಪರೇ ।\n\nಪ್ರಾಣ ಅಪಾನ ಗತೀ ರುದ್ಧ್ವಾ ಪ್ರಾಣಾಯಾಮ ಪರಾಯಣಾಃ -ವತ್ತೆ ಕೆಲವರು ಪ್ರಾಣಾಯಾಮದ ಸಾಧಕರು.\nಪ್ರಾಣಾಪಾನಗಳ ನಡೆಯನ್ನು ತಡೆಹಿಡಿದು ಅಪಾನದಲ್ಲಿ ಪ್ರಾಣವನ್ನು ಹೋಮಿಸುತ್ತಾರೆ. ಪ್ರಾಣದಲ್ಲಿ\nಅಪಾನವನ್ನು.\n\nಯೋಗದಲ್ಲಿ ವಿಶಿಷ್ಟ ವಾದ ಸಾಧನೆ ಪ್ರಾಣಯಾಮ. ಕೆಲವರಿಗೆ ಪ್ರಾಹಾಯಾಮವೇ ಬದುಕಿನಲ್ಲಿ ಒಂದು ಸಾಧನೆ.\nಪ್ರಾಣಾಪಾನಗಳನ್ನು ಭಗವಂತನಲ್ಲಿ ಯಜ್ಞ ರೂಪವಾಗಿ ಅರ್ಪಿಸಿ, ಪ್ರಾಣಾಯಾಮದಿಂದ ಭಗಂತನ ಉಪಾಸನೆ-\nಅಪಾನದಲ್ಲಿ ಪ್ರಾಣವನ್ನು ಹೋಮಿಸುವುದು. ಇದು ಕುಂಭಕಕ್ಕೆ ಸಂಬಂಧಪಟ್ಟದ್ದು. ದೇಹದ ಒಳಗಿನಿಂದ\nಶ್ವಾಸವನ್ನು ಹೊರಬಿಡುವುದು 'ರೇಚಕ'; ಆಮ್ಲಜನಕಯುಕ್ತ ಶುದ್ಧ ಗಾಳಿಯನ್ನು ಒಳಗೆ ತೆಗೆದುಕೊಳ್ಳುವುದು\n'ಪೂರಕ'. ನಮ್ಮ ಹೃದಯ ಕಲಶದಲ್ಲಿ ಪ್ರಾಣಶಕ್ತಿಯನ್ನು ಹಿಡಿದಿಡುವುದು-“ಕುಂಭಕ'. ಇದು ಬಹಳ ಪರಿಣಾಮಕಾರಿ.\n\nಇದರಿಂದ ಏಕಾಗ್ರತೆ, ಆರೋಗ್ಯ, ಆಯುಸ್ಸು ಹೆಚ್ಚುತ್ತದೆ. ಸಾಮಾನ್ಯವಾಗಿ ಒಬ್ಬ ಮನುಷ್ಯನ ಆಯುಸ್ಸು ಆತನ\nಉಸಿರಾಟದ ಮೇಲೆ ನಿರ್ಧಾರವಾಗಿರುತ್ತದೆ. ಸಹಜ ಉಸಿರಾಟ ಎಂದರೆ ನಾಲ್ಕು ಸೆಕೆಂಡಿಗೆ ಒಂದು\nಉಸಿರಾಟ(ರೇಚಕ ಮತ್ತು ಪೂರಕ). ಒಬ್ಬ ಮನುಷ್ಯ ನೂರು ವರ್ಷ ಬದುಕುತ್ತಾನೆ ಎಂದರೆ ಆತನ ಆಯುಸ್ಸು\n'೭೭ ಕೋಟಿ, ೭೬ ಲಕ್ಷ ಉಸಿರು'. ಒಂದು ವೇಳೆ ನಾಲ್ಕು ಸೆಕೆಂಡಿಗೆ ಬದಲಾಗಿ ೮ ಸೆಕೆಂಡಿಗೊಮ್ಮೆ ಉಸಿರಾಟ\nಮಾಡಿದರೆ ಆತ ೨೦೦ ವರ್ಷ ಬದುಕಬಹುದು. ಇದನ್ನು ಹಿಂದೆ ಕೆಲವು ಸಾಧಕರು ಪ್ರಾಣಾಯಾಮದಿಂದ\nಸಾಧಿಸುತ್ತಿದ್ದರು. ಇಂದೂ ಕೂಡಾ ಹಿಮಾಲಯದಲ್ಲಿ ನೂರಾರು ವರ್ಷ ವಯಸ್ಸಾಗಿರುವ ಆರೋಗ್ಯಪೂರ್ಣ\nಸಾಧಕರಿದ್ದಾರೆ.. ಎಂದು ಪರಮಹಂಸ ಯೋಗಾನಂದರು ಮತ್ತು\nಸ್ವಾಮಿ ರಾಮರು (in their book) ತಮ್ಮ ಸ್ವಂತ ಅನುಭವದಿಂದ ಹೇಳಿದ್ದಾರೆ.\nಪ್ರಾಣಾಯಾಮದಿಂದ ಪ್ರಾಣಶಕ್ತಿ ವೃದ್ಧಿಗೊಳ್ಳುತ್ತದೆ. ಇದರಿಂದ ಇನ್ನೊಬ್ಬರ ರೋಗವನ್ನು ಕೂಡಾ\nಗುಣಪಡಿಸಬಹುದು. ಇದನ್ನು ಸ್ಪರ್ಶ ಅಥವಾ ಸ್ಪರ್ಶ ಚಿಕಿತ್ಸೆ (healing touch) ಎನ್ನು ತ್ತಾರೆ. ಕೇವಲ ಹಸ್ತ ಸ್ಪರ್ಶದಿಂದ ಭಯ,\nರೋಗ, ದುಃಖ, ಹುಚ್ಚು, ಕುರುಡುತನ ಎಲ್ಲವನ್ನೂ ಗುಣ ಪಡಿಸಬಹುದು. ಈ ಕಾರಣಕ್ಕಾಗಿ ಒಬ್ಬರು ಇನ್ನೊಬ್ಬ ರಿಗೆ\nಆಶೀರ್ವಾದ ಮಾಡುವಾಗ ತಲೆ ಮೇಲೆ ಕೈ ಇಟ್ಟು ಮಾಡುತ್ತಾರೆ. ಇದರಿಂದ ಪ್ರಾಣ ಶಕ್ತಿ ದೊಡ್ಡವರಿಂದ\nಚಿಕ್ಕವರಿಗೆ ಹರಿಯುತ್ತದೆ. ಹೀಗೆ ಪ್ರಜಾಯಾಮದಲ್ಲಿ ಅನೇಕ ಸಾಧನೆ ಸಾಧ್ಯ. ಮುಖ್ಯವಾಗಿ ಇದರಿಂದ ಮನಸ್ಸು\nದೇವರಲ್ಲಿ ನೆಲೆಗೊಳ್ಳುತ್ತದೆ. ಕೃಷ್ಣ ಇದನ್ನು ಯಜ್ಞ ಎನ್ನುತ್ತಾನೆ.\n\nಮೇಲಿನಿಂದ ಕೆಳಕ್ಕೆ ಹರಿಯುವ ಶಕ್ತಿ ಅಪಾನ, ಊರ್ಧ್ವ ಮುಖವಾಗಿ ಮೂಲಾಧಾರದಿಂದ ಸಹಸ್ರಾರದತ್ತ\nಹರಿಯುವ ಶಕ್ತಿ ಪ್ರಾಣ. ಈ ಎರಡು ಶಕ್ತಿಗಳನ್ನು ಹೃದಯದಲ್ಲಿ ಸ್ಥಗಿತ ಮಾಡುವುದು ಕುಂಭಕ. ಪೂರ್ಣವಾಗಿ\nಒಳಗಿನ ಗಾಳಿಯನ್ನು ತನ್ನ ಬಲ ಮೂಗಿನ ಹೊರಳೆಯಿಂದ ಹೊರ ಹಾಕಿ, ತನ್ನ ಎಡ ಮೂಗಿನ ಹೊರಳೆಯಿಂದ\nಶುದ್ಧ ಗಾಳಿಯನ್ನು ಇನ್ನು ಒಳಗೆ ಹೋಗುವುದಿಲ್ಲ ಅನ್ನುವಷ್ಟು ಪ್ರಮಾಣದಲ್ಲಿ ತೆಗೆದುಕೊಂಡು, ಪ್ರಾಣಶಕ್ತಿ\nಮೇಲಕ್ಕೆ ಹೋಗದಂತೆ, ಅಪಾನ ಕೆಳಗೆ ಹೋಗದಂತೆ ಶಕ್ತಿಯನ್ನು ಹೃದಯದಲ್ಲಿ ಸ್ಥಗಿತ ಗೊಳಿಸುವುದು- ಕುಂಭಕ.\nಇದು ಪ್ರಾಣಾಯಾಮ ಪರಾಯಣರು ಮಾಡುವ ಯಜ್ಞ. ಭಗವಂತ ಪ್ರಸನ್ನನಾಗಿ ನನಗೆ ಏಕಾಗ್ರತೆಯನ್ನು ಕೊಟ್ಟು,\nನನ್ನ ಸಾಧನೆಯನ್ನು ಮುಂದುವರಿಸಲು ಸಹಕರಿಸಲಿ ಎನ್ನುವ ಅನುಸಂಧಾನದಿಂದ ಮಾಡುವ ಉಸಿರಾಟದ\nಯಜ್ಞ. [ಸೂಚನೆ:ಗುರುವಿನ ಮಾರ್ಗದರ್ಶನವಿಲ್ಲದೆ ಪ್ರಾಹಾಯಾಮವನ್ನು ಪ್ರಯತ್ನಿಸಬಾರದು]",
  "4.30": "ಅಪರೇ ನಿಯತ ಆಹಾರಾಃ ಪ್ರಾಣಾನ್‌ ಪ್ರಾಣೇಷು ಜುಹ್ವತಿ |\n\nಸರ್ವೇ ಅಪಿ. ಏತೇ ಯಜ್ಞವಿದಃ ಯಜ್ಞಕ್ಷಪಿತ ಕಲ್ಮಷಾಃ -ಕೆಲವರು ಆಹಾರವನ್ನು ಮಿತಗೊಳಿಸಿ\nಇಂದ್ರಿಯವೃತ್ತಿಗಳನ್ನು ಇಂದ್ರಿಯಗಳಲ್ಲಿ ಹೋಮಿಸುತ್ತಾರೆ.[ಕಿರಿಯರಾದ ಇಂದ್ರಿಯ ದೇವತೆಗಳು ಹಿರಿಯರಾದ\nಇಂದ್ರಿಯ ದೇವತೆಗಳಿಗೆ ಅಧೀನರೆಂದು ಚಿಂತನೆ ಮಾಡುತ್ತಾರೆ] ಇವರೆಲ್ಲರೂ ಯಜ್ಞದ ಬಗೆಯನ್ನು ಬಲ್ಲವರು;\nಯಜ್ಞದಿಂದ ಕೊಳೆಯನ್ನು ತೊಳೆದುಕೊಂಡವರು.\n\nಕೆಲವರು ಆಹಾರ ನಿಯಂತ್ರಣಗೊಳಿಸಿ, ಇಂದ್ರಿಯ ಚಾಪಲವನ್ನು ಕಡಿಮೆ ಮಾಡಿಕೊಂಡು ಸಾಧನೆ ಮಾಡುತ್ತಾರೆ.\nಆಹಾರ ನಿಯಂತ್ರಣ ಎಂದರೆ ಹೆಚ್ಚು ಆಹಾರ ಸೇವಿಸದೇ ಇರುವುದು, ಉಪ್ಪು-ಹುಳಿ-ಖಾರ ಕಡಿಮೆ ತಿನ್ನುವುದು\nಇತ್ಯಾದಿ. ಇದರಿಂದ ಇಂದ್ರಿಯ ಸೆಳೆತ ಕಡಿಮೆಯಾಗುತ್ತದೆ. ಇದರ ಪರಿಣಾಮ ನೇರವಾಗಿ ಮನಸ್ಸಿನ ಮೇಲೆ.\nಹೀಗೆ ಆಹಾರ ನಿಯಂತ್ರಣದ ಮೂಲಕ ಸಾಧನೆ ಒಂದು ಯಜ್ಞ. ಈ ಕಾರಣಕ್ಕಾಗಿ ನಮ್ಮಲ್ಲಿ ಅನೇಕ ಹಬ್ಬ\nಹರಿದಿನಗಳಲ್ಲಿ, ಏಕಾದಶಿಯಂದು-ಉಪವಾಸ ಪದ್ಧತಿ ಸಾಮಾಜಿಕವಾಗಿ ನೆಡೆದು ಬಂತು. ಇದರಿಂದ ಕನಿಷ್ಠ ಆ\nಒಂದು ದಿನವಾದರೂ ಮನಸ್ಸು ಸ್ವಚ್ಛವಾಗಿ ಭಗವಂತನ ಉಪಾಸನೆಯಲ್ಲಿ ತೊಡಗಲಿ ಎನ್ನುವುದು ಇದರ\nಹಿಂದಿನ ಸಂಕಲ್ಪ.\n\nಇನ್ನೊಂದು ವಿಧವಾದ ಯಜ್ಞ \"ಪ್ರಾಣಾನ್‌ ಪ್ರಾಣೇಷು ಜುಹ್ವತಿ\" ಅಂದರೆ ಪ್ರಾಣಗಳಲ್ಲಿ ಪ್ರಾಣವನ್ನು\nಹೋಮಿಸುವುದು ಅಥವಾ ಇಂದ್ರಿಯಗಳಲ್ಲಿ ಇಂದ್ರಿಯವನ್ನು ಹೋಮಿಸುವುದು. ಇಲ್ಲಿ ಇಂದ್ರಿಯಗಳು ಎಂದರೆ\nಇಂದ್ರಿಯಾಭಿಮಾನಿ ದೇವತೆಗಳು. ನಮ್ಮ ಪ್ರತಿಯೊಂದು ಇಂದ್ರಿಯಕ್ಕೂ ಒಬ್ಬ ಅಭಿಮಾನಿ ದೇವತೆ ಇದ್ದಾನೆ. ಈ\nದೇವತೆಗಳು ಒಂದೊಂದು ಸ್ತರದಲ್ಲಿ ಕೆಲಸ ಮಾಡುತ್ತಾರೆ. ಒಬ್ಬೊಬ್ಬ ದೇವತೆಯೂ ಒಂದೊಂದು\nಮೆಟ್ಟಲಿನಲ್ಲಿ ನಿಂತು ಕಾರ್ಯ ನಿರ್ವಹಿಸುತ್ತಿರುತ್ತಾರೆ ಹಾಗೂ ಇವರು ಭಗವಂತನನ್ನು ಸೇರುವಲ್ಲಿ ನಮಗೆ\nಸಹಾಯ ಮಾಡುತ್ತಾರೆ. ಈ ದೇವತೆಗಳನ್ನು ವಿವಿಧ ಮೆಟ್ಟಲಿನಲ್ಲಿ ತಾರತಮ್ಯ ಚಿಂತನೆ ಮಾಡುವುದು, ಅದರ\nಮುಖೇನ ಭಗವಂತನ ಚಿಂತನೆ ಒಂದು ಯಜ್ಞ. ಸರ್ವೋತ್ತಮನಾದ ಭಗವಂತ ಮೊದಲಿನವನು. ಎಲ್ಲವೂ ಅವನ\nಅಧೀನ. ಆತನ ನಂತರ ಪ್ರಕೃತಿ ಮಾತೆ ಲಕ್ಷ್ಮಿ, ನಂತರ ಬ್ರಹ್ಮ-ವಾಯು, ಸರಸ್ವತಿ-ಭಾರತಿ, ಗರುಡ-ಶೇಷ-ರುದ್ರ,\nಸುಪರ್ಣಿ-ವಾರುಣಿ-ಪಾರ್ವತಿ, ಇಂದ್ರ-ಕಾಮರು, ದಕ್ಷಾದಿಗಳು, ಸೂರ್ಯ-ಚಂದ್ರ-ಯಮಾದಿಗಳು, ವರುಣ, ಅಗ್ನಿ,\nಅಶ್ವೀದೇವತೆಗಳು, ಕುಬೇರ, ಯಜ್ಞ. ಹೀಗೆ ಒಬ್ಬರು ಇನ್ನೊ ಬ್ಬರಿಗೆ ಅಧೀನವಾಗಿ ವಿವಿಧ ಮೆಟ್ಟ ಲಿನಲ್ಲಿ ಕಾರ್ಯ\nನಿರ್ವಹಿಸುತ್ತಿರುತ್ತಾರೆ. ಈ ರೀತಿ ದೇಹ ಎನ್ನುವ ಈ ಅದ್ಭುತ ಯಂತ್ರವನ್ನು ನಿಯಂತ್ರಿಸುವ ದೇವತೆಗಳ ಅರಿವು,\nಅದರ ಮೂಲಕ ಭಗವಂತನೆಡೆಗೆ ಸಾಗುವ ಜ್ಞಾನಸಾಧನೆ-ತಾರತಮ್ಯ ಜ್ಞಾನಯಜ್ಞ.\n\nಯಜ್ಞದಲ್ಲಿ ಒಂದು ಒಳ್ಳೆಯದು ಒಂದು ಕೆಟ್ಟದ್ದು ಅನ್ನುವುದಿಲ್ಲ. ಯಾರಿಗೆ ಯಾವ ಯಜ್ಞ ಒಗ್ಗುತ್ತದೋ ಅದರ\nಮುಖೇನ ಸಾಧನೆ ಮಾಡುತ್ತಾರೆ. ಎಲ್ಲರೂ ಎಲ್ಲವನ್ನೂ ಮಾಡಲು ಸಾಧ್ಯವಿಲ್ಲ. ಯಾರಿಗೆ ಯಾವುದು\nಹಿತವೆನಿಸುತ್ತದೋ, ಸಾಧನೆಗೆ ಅನುಕೂಲವಾಗುತ್ತದೋ, ಆ ದಾರಿಯಲ್ಲಿ ಸಾಗಬೇಕು. ಯಜ್ಞದಿಂದ\nಆರಾಧ್ಯನಾದ ಯಜ್ಞಮೂರ್ತಿಯಾದ ಭಗವಂತನತ್ತ ಸಾಗುವವನು, ತನ್ನ ಜೀವನದ ಪ್ರತಿಯೊಂದು ನಡೆಯನ್ನು\nಭಗವಂತನ ಆರಾಧನೆಯಾಗಿ ಮಾಡಿಕೊಳ್ಳುವ ಮೂಲಕ, ತನ್ನ ಬದುಕಿನ ಕಲ್ಮಶವನ್ನು ತೊಳೆದುಕೊಂಡು\nಸ್ವಚ್ಛವಾದ ಬದುಕನ್ನು ಬಾಳುತ್ತಾನೆ.",
  "4.31": "ಯಜ್ಞ ಶಿಷ್ಟ ಅಮೃತ ಭುಜಃ ಯಾಂತಿ ಬ್ರಹ್ಮ ಸನಾತನಮ್‌ |\n\nನ ಅಯಮ್‌ ಲೋಕ: ಅಸ್ತಿ ಅಯಜ್ಞಸ್ಯ ಕುತಃ ಅನ್ಯಃ ಕುರುಸತ್ತಮ -- ಯಜ್ಞದಲ್ಲಿ ಅರ್ಪಿಸಿ ಉಳಿದ\nಅಮೃತವನ್ನುಣ್ಣುವವರು(ಯಜ್ಞ ಫಲದ ಅಮೃತ) ಶಾಶ್ವತವಾದ ಭಗವಂತನನ್ನು ಪಡೆಯುತ್ತಾರೆ. ಓ\nಕುರುಶ್ರೇಷ್ಠಾ, ಯಜ್ಞವಿರದವನಿಗೆ ಈ ಲೋಕವೇ ಇಲ್ಲ. ಆ ಲೋಕದ ಮಾತೇನು?\n\nಯಜ್ಞದಲ್ಲಿ ಭಗವಂತನಿಗೆ ಅರ್ಪಿಸಿ ಉಳಿದದ್ದನ್ನು 'ಅಮೃತ' ಎನ್ನುತ್ತಾರೆ. ಅದು ನಮ್ಮನ್ನು ಸಾವಿನಿಂದಾಚೆಗೆ\nಕೊಂಡೊಯ್ಯುತ್ತದೆ. ಜೀವನದ ಪ್ರತಿಯೊಂದು ನಡೆಯಲ್ಲಿ ಈ ರೀತಿಯ ಬದುಕನ್ನು ಬದುಕುತ್ತಿದ್ದರೆ ಕ್ರಮೇಣ\nಎಂದೆಂದೂ ಬದಲಾಗದ, ಶಾಶ್ವತ ಮತ್ತು ಸನಾತನನಾದ ಭಗವಂತನನ್ನು ಹೋಗಿ ಸೇರುತ್ತೇವೆ.\n\nಇಲ್ಲಿ 'ಸನಾತನ' ಎನ್ನುವಲ್ಲಿ ಇನ್ನೊಂದು ಧ್ವನಿ ಇದೆ. ಕೇವಲ ಉಪವಾಸ ಪ್ರಾಣಾಯಾಮ ಮಾಡಿದಾಗ ಮೋಕ್ಷ\nಸಿಗದು. ಸನಾತನ(ನಾತನ-ನಾದನ) ಅಂದರೆ ಶಬ್ದ. ಬ್ರಹ್ಮ ಸನಾತನ ಎಂದರೆ ಸರ್ವಶಬ್ದ ವಾಚ್ಯನಾದ,\nವೇದವೇದ್ಯ ಭಗವಂತ. ಇಂತಹ ಭಗವಂತನನ್ನು ಶಾಸ್ತ್ರದ ಮುಖೇನ ತಿಳಿದುಮಾಡುವ ಯಜ್ಞದಿಂದ ಮೋಕ್ಷ\nಸಾಧ್ಯ. ಇಲ್ಲದಿದ್ದರೆ ಏನೂ ಉಪಯೋಗವಿಲ್ಲ. ವೇದದಲ್ಲಿ ಹೇಳಿರುವ ಗುಣವನ್ನು ಬಲ್ಲವರಿಂದ ತಿಳಿದು ಉಪಾಸನೆ\nಮಾಡುವವ, ವೇದವನ್ನು ಓದಿ ಅದರಿಂದ ತಿಳಿದವ, ತಿಳಿದು ಇನ್ನೊಬ್ಬರಿಗೆ ಹೇಳುವವ, ಹೀಗೆ ಎಲ್ಲರೂ\nಸಾಧಕರೆನಿಸುತ್ತಾರೆ. ಯಜ್ಞದಲ್ಲಿ ಪ್ರಮುಖವಾಗಿ ಬೇಕಾಗಿರುವುದು ಜ್ಞಾನ, ಅನನ್ಯ ಭಕ್ತಿ ಮತ್ತು ಶರಣಾಗತಿ.\n\"ಜೀವನದಲ್ಲಿ ಈ ಅನುಸಂಧಾನವಿಲ್ಲದವ, ಯಜ್ಞವನ್ನು ಬದುಕಿನಲ್ಲಿ ಅಳವಡಿಸಿಕೊಳ್ಳದವ, ಇಹದಲ್ಲೂ\nವ್ಯರ್ಥವಾಗಿ ಬದುಕುತ್ತಾನೆ-ಇನ್ನು ಪರದ ಮಾತೇನು” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.\n\nಇಲ್ಲಿ ಅರ್ಜುನನನ್ನು ಕೃಷ್ಣ 'ಕುರುಸತ್ತಮ' ಎಂದು ಸಂಬೋಧಿಸಿದ್ದಾನೆ. ಕುರುವಂಶದಲ್ಲಿ ಶ್ರೇಷ್ಠನಾದ ನೀನು\nನಿಷ್ಕ ೀಯನಾಗದೇ ಕಾರ್ಯ ಪ್ರವೃತ್ತನಾಗು; ಯಜ್ಞದಲ್ಲಿ ತಮ್ಮನ್ನು ತೊಡಗಿಸಿಕೊಂಡು ಬಂದ ವಂಶದಲ್ಲಿ ಹುಟ್ಟಿದ\nಜ್ಞಾನಿಶ್ರೇಷ್ಠ, ಸಾತ್ವಿಕನಾದ ನೀನು- 'ಯುದ್ಧವನ್ನು ಯಜ್ಞವಾಗಿ ಮಾಡು' ಎನ್ನುವ ಧ್ವನಿ ಈ ಸಂಬೋಧನೆಯಲ್ಲಿದೆ.",
  "4.32": "ಏವಮ್‌ ಬಹುವಿಧಾಃ ಯಜ್ಞಾಃ ವಿತತಾಃ ಬ್ರಹ್ಮಣಃ ಮುಖೇ\n\nಕರ್ಮಜಾನ್‌ ವಿದ್ಧಿ ತಾನ್‌ ಸರ್ವಾನ್‌ ಏವಮ್‌ ಜ್ಞಾತ್ವಾ ವಿಮೋಕ್ಷ್ನಸೇ- ಹೀಗೆ ಹಲವು ಬಗೆಯ ಯಜ್ಞಗಳು\nಭಗವಂತನ ಬಾಯಲ್ಲಿ ಹರವಿಕೊಂಡಿವೆ. ಅವೆಲ್ಲವೂ ಕರ್ಮದಿಂದಲೇ ಆಗುವಂತವು ಎನ್ನುವುದನ್ನು ತಿಳಿ. ಹೀಗೆ\nತಿಳಿದರೆ ಬಿಡುಗಡೆ ಹೊಂದುವೆ.\n\nಯಜ್ಞ ಅನ್ನುವುದಕ್ಕೆ ಹಲವು ಮುಖ. ಬದುಕಿನ ಯಾವುದೇ ನಡೆಯನ್ನು ಭಗವಂತನ ಪ್ರಜ್ಞೆಯಿಂದ ಮಾಡಿದಾಗ,\nಬದುಕಿನ ನಡೆ ಭಗವಂತನ ಕಡೆ ಸಾಗುವ ನಡೆಯಾದಾಗ, ಅದು ಯಜ್ಞವಾಗುತ್ತದೆ. ಯಾವ ರೀತಿ ಯಜ್ಞ\n\nಮಾಡಿದರೂ ಅದು ಭಗವಂತನ ಮುಖದಲ್ಲೇ ಬಂದು ಸೇರುತ್ತದೆ... ಸರ್ವಯಜ್ಞಗಳ ನಿಯಾಮಕ ಆ\nಭಗವಂತನೊಬ್ಬನೇ, ವೈವಿಧ್ಯತೆ ಕೇವಲ ನಮ್ಮ ಅನುಸಂಧಾನ ಮತ್ತು ಕ್ರಿಯೆಯಲ್ಲಿ.\n\nನಾವು ನಮ್ಮ ಕರ್ಮದ ಮುಖೇನ ಯಜ್ಞ ಮಾಡಬೇಕು. ಕರ್ಮವನ್ನು ಬಿಟ್ಟು ಭಗವಂತನ ಉಪಾಸನೆ\nಮಾಡುತ್ತೇನೆ ಎಂದು ಹೊರಟರೆ ಅದು ಸಾಧ್ಯವಿಲ್ಲ. ನಾವು ನಮ್ಮನಮ್ಮ ಕರ್ತವ್ಯ ಕರ್ಮದಲ್ಲಿ ಭಗವಂತನನ್ನು\nಕಾಣುವುದು ಯಜ್ಞ. ಈ ಅನುಸಂಧಾನದಿಂದ ಯಾವ ಕರ್ಮ ಮಾಡಿದರೂ ಅದು ನಮ್ಮನ್ನು ಬಿಡುಗಡೆಯ\nಮಾರ್ಗದತ್ತ ಕೊಂಡೊಯ್ಯುತ್ತದೆ.\n\nಈವರೆಗೆ ಕೃಷ್ಣ ಕರ್ಮ-ಯಜ್ಞವಾಗುವುದು ಹೇಗೆ, ಅದರಲ್ಲಿನ ವಿಧ, ಅದರ ಸ್ವಾಮಿ- ಈ ವಿಚಾರವನ್ನು ವಿವರವಾಗಿ\nಹೇಳಿದ. ಮೂಲಭೂತವಾಗಿ ಯಜ್ಞದಲ್ಲಿ ಬಾಹ್ಯ ಮತ್ತು ಅಂತರಂಗ ಯಜ್ಞ ಎನ್ನುವುದನ್ನೂ ನಾವು ನೋಡಿದೆವು.\nಈ ಎರಡು ವಿಧವಾದ ಯಜ್ಞದಲ್ಲಿ ಯಾವುದಕ್ಕೆ ಹೆಚ್ಚು ಮಹತ್ವ ಮತ್ತು ಏಕೆ-ಈ ಕುರಿತು ಕೃಷ್ಣ ಮುಂದಿನ\nಶ್ಲೋಕದಲ್ಲಿ ವಿವರಿಸುತ್ತಾನೆ.",
  "4.33": "ಶ್ರೇಯಾನ್‌ ದ್ರವ್ಯ ಮಯಾತ್‌ ಯಜ್ಞಾತ್‌ ಜ್ಞಾನಯಜ್ಞಃ ಪರಂತಪ |\n\nಸರ್ವಮ್‌ ಕರ್ಮಾ ಅ[ಆ]ಖಿಲಮ್‌ ಪಾರ್ಥ ಜ್ಞಾನೇ ಪರಿಸಮಾಪ್ಯತೇ- ಓ ಪರಂತಪಾ, ಸೊತ್ತುಗಳನ್ನು\nಹೋಮಿಸುವ ಬಾಹ್ಯ ಯಜ್ಞಕ್ಕಿಂತ ಜ್ಞಾನ ಯಜ್ಞ ಮಿಗಿಲು. ಓ ಪಾರ್ಥಾ, ಸಾಂಗವಾದ [ತಿಳಿವಿನೆದುರು ತೀರಾ\nಸಣ್ಣದಾದ] ಎಲ್ಲಾ ಕರ್ಮವೂ ತಿಳಿವಿನಲ್ಲಿ ಪೂರ್ತಿಗೊಳ್ಳುತ್ತದೆ.\n\nವಾಸ್ತವಿಕವಾಗಿ ಪೂರ್ಣವಾದ ಬರಿಯ ಬಾಹ್ಯಯಜ್ಞ ಮತ್ತು ಬರಿಯ ಅಂತರಂಗ ಯಜ್ಞ ಅನ್ನುವುದೊಂದಿಲ್ಲ. ನಾವು\nಮಾಡುವ ಬಾಹ್ಯಯಜ್ಞದ ಹಿಂದೆ ಅರಿವಿದೆ. ಅಂತರಂಗ ಯಜ್ಞದ ಜೊತೆಗೆ ಆಚರಣೆ ಕೂಡಾ ಇದೆ. ಇವೆರಡರಲ್ಲಿ\nಅಂತರಂಗ ಯಜ್ಞಕ್ಕೆ ಹೆಚ್ಚು ಮಹತ್ವ. ಏಕೆಂದರೆ ನಾವು ಮಾನಸಿಕವಾಗಿ ಧ್ಯಾನ ಮಾಡುವುದರಿಂದ ಬಾಹ್ಯಕ್ರಿಯೆ\nಇಲ್ಲದೆ ಮನಸ್ಸಿ ನಲ್ಲಿ ವಿಶೇಷ ಶಕ್ತಿ ನಿರ್ಮಾಣವಾಗುತ್ತದೆ. ಆದರೆ ಅರಿವು ಇಲ್ಲದೇ ಕರ್ಮ ಮಾಡಿದರೆ ಅದು ವ್ಯರ್ಥ!\nಈ ಕಾರಣಕ್ಕಾಗಿ ಕರ್ಮದ ಹಿಂದಿನ ಅರಿವು ಬಹಳ ಮುಖ್ಯ. ಹಾಗಾಗಿ ಜ್ಞಾನಪೂರ್ವಕ ನಾವು ಕರ್ಮ ಮಾಡಬೇಕು.\nಬರೀ ದ್ರವ್ಯಮಯವಾಗಿ, ಅದರ ಹಿಂದೆ ಜ್ಞಾನ ಇಲ್ಲದೇ ಇದ್ದರೆ, ತಿಳಿದು ಮಾಡದಿದ್ದರೆ, ಅದಕ್ಕೆ ಅರ್ಥವಿಲ್ಲ. ಯಾವ\nಕರ್ಮವನ್ನಾಗಲಿ ತಿಳಿದು ಮಾಡಿದಾಗ ಮಾತ್ರ ಪರಿಣಾಮಕಾರಿ. ಈ ಕಾರಣದಿಂದ ಜ್ಞಾನಪರವಾದ ಯಜ್ಞ\nಮಹತ್ವದ್ದು. ಈ ಶ್ಲೋಕದಲ್ಲಿ ಕೃಷ್ಣ ಅರ್ಜುನನನ್ನು ಪರಂತಪ ಎಂದು ಸಂಬೋಧಿಸುತ್ತಾನೆ. ಇಲ್ಲಿ ಈ\nಸಂಬೋಧನೆಗೆ ವಿಶೇಷ ಅರ್ಥವಿದೆ. ಈ ಪದವನ್ನು ಎರಡು ನೆಲೆಯಲ್ಲಿ ಅರ್ಥೈಸಬಹುದು. ಸ್ಥೂಲವಾಗಿ\nನೋಡಿದರೆ ಪರಂತಪ ಎಂದರೆ 'ಶತ್ರುಗಳನ್ನು ಸದೆಬಡಿಯುವ ವೀರ'. ಇಲ್ಲಿ ಅರ್ಜುನ ಮಾಡುತ್ತಿರುವ ಯಜ್ಞ\nಶತ್ರುನಿಗ್ರಹ. ಆ ಯಜ್ಞದ ಹಿಂದೆ ಜ್ಞಾನದ ಸಹಕಾರವಿದೆ. ಆದ್ದರಿಂದ ಅದು ಜ್ಞಾನಯಜ್ಞವಾಗುತ್ತದೆ-\nದ್ರವ್ಯಯಜ್ಞವಲ್ಲ. ಏಕೆಂದರೆ ಅರ್ಜುನ ಪರಂತಪ-'ಪರಮಾತ್ಮನನ್ನು ಸದಾ ಚಿಂತಿಸುವವನು'. ಇಲ್ಲಿ 'ಅವರು ನನ್ನ\n\nಶತ್ರುಗಳು, ಅವರನ್ನು ನಿಗ್ರಹಿಸಿ ನಾನು ಅಧಿಕಾರ ಸಾಧಿಸಬೇಕು' ಎನ್ನುವ ಅನುಸಂಧಾನವಿಲ್ಲ. ಇದೊಂದು\nಭಗವಂತನ ಆರಾದನಾ ರೂಪವಾದ ಯಜ್ಞ. ಅನ್ಯಾಯದ ವಿರುದ್ಧ ಹೋರಾಟ ಅರ್ಜುನನ ಕರ್ತವ್ಯ,\nಜಯಾಪಜಯಗಳು ಆ ಭಗವಂತನಿಗೆ ಬಿಟ್ಟಿದ್ದು. ಈ ಅನುಸಂಧಾನದಿಂದ ಯುದ್ಧ ಮಾಡಿದಾಗ ಅದು\nಜ್ಞಾನಯಜ್ಞವಾಗುತ್ತದೆ. ಪರಂತಪ ಎನ್ನುವ ಈ ವಿಶೇಷಣ ಇಲ್ಲಿ ಕರ್ಮವನ್ನು ಜ್ಞಾನವಾಗಿ ಹೇಗೆ\nಪರಿವರ್ತಿಸಬಹುದು ಎನ್ನುವುದನ್ನು ಸೂಚಿಸುತ್ತದೆ.\n\nಇದು ಏಕೆ ಜ್ಞಾನಮಯ ಎನ್ನುವುದನ್ನು ಕೃಷ್ಣ ವಿವರಿಸುತ್ತಾ ಹೇಳುತ್ತಾನೆ: \"ಸರ್ವಮ್‌ ಕರ್ಮಾ ಅಖಿಲಂ\" ಎನ್ನುವುದನ್ನು ಎರಡು\nಬಗೆಯಿಂದ ಪದಛೇದ ಮಾಡಬಹುದು. ಒಂದು- “ಸರ್ವ ಕರ್ಮ ಅಖಿಲಂ' ಹಾಗೂ ಇನ್ನೊಂದು “ಸರ್ವ ಕರ್ಮ\nಆಖಿಲಂ'. ಎಲ್ಲಾ ಪರಿಕರಗಳಿಂದ ಪರಿಪೂರ್ಣವಾದ ಸರ್ವಕರ್ಮವನ್ನು 'ಸರ್ವ ಕರ್ಮ ಅಖಿಲಂ ಎನ್ನುತ್ತಾರೆ.'\nಅಂದರೆ ಪರಿಪೂರ್ಣವಾದ ಎಲ್ಲಾ ಕರ್ಮ. \"ಒಂದು ಕರ್ಮವನ್ನು ಪೂರ್ಣವಾಗಿ ಮಾಡು” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.\nಯಾವುದೇ ಕರ್ಮವನ್ನು ಜ್ಞಾನಪೂರ್ವಕವಾಗಿ ಮಾಡಿದಾಗ ಮಾತ್ರ ಅದು ಪೂರ್ಣವಾಗುತ್ತದೆ. ಕರ್ಮದ ಜೊತೆಗೆ\nಜ್ಞಾನ ಬೇಕೇಬೇಕು. ಅದು ಜ್ಞಾನದ ಶ್ರೇಷ್ಠತೆ. ಜ್ಞಾನದಿಂದ ಕರ್ಮ ಮಾಡು; ಕರ್ಮ ಮಾಡಿ ಜ್ಞಾನಗಳಿಸು. ಆಗ\nಅದು ಪರಿಪೂರ್ಣ. ಭಾಗವತದಲ್ಲಿ ಜ್ಞಾನವಿಲ್ಲದೇ ಮಾಡುವ ಯಜ್ಞವನ್ನು ಉಗ್ರವಾಗಿ ವಿರೋಧಿಸುತ್ತಾರೆ. ಅಲ್ಲಿ\nಹೋಮದಲ್ಲಿ ಕೊಡುವ ಆಹುತಿಯನ್ನು ಏಕೆ ಕೊಡುತ್ತಿದ್ದೇವೆ ಎಂದು ತಿಳಿಯದೇ ಹೋಮ ಮಾಡುವವನು ಬೆಂಕಿಗೆ\nಮರುಳಾದವನು ಹಾಗೂ ಹೊಗೆ ತಿಂದು ಸಾಯುವವನು' ಎನ್ನುತ್ತಾರೆ. ಕರ್ಮದ ಹಿಂದಿನ ಭಗವಂತನ ಅರಿವು\nಬಹಳ ಮುಖ್ಯ. ಇಲ್ಲದಿದ್ದರೆ ಅದು ತೂತು ಬಿದ್ದ ದೋಣಿಯಂತೆ. ಮಾಡಿದ ಕರ್ಮ ಸಫಲವಾಗುವುದು ಅದರ ಹಿಂದೆ\nಅರಿವು ಇದ್ದಾಗ ಮಾತ್ರ.\n\nಇನ್ನೊಂದು ಅರ್ಥದಲ್ಲಿ ಜ್ಞಾನರಹಿತವಾದ ಕೇವಲಕರ್ಮ 'ಆ-ಖಿಲಂ'. ಇಲ್ಲಿ 'ಖಿಲಂ' ಅಂದರೆ ಚೂರು. ಜ್ಞಾನವಿಲ್ಲದ\nಎಲ್ಲಾ ಕರ್ಮವನ್ನು ಒಂದುಗೂಡಿಸಿದರೂ ಅದು ಜ್ಞಾನದ ಮುಂದೆ ಒಂದು ಚಿಕ್ಕ ಚೂರು. ಜ್ಞಾನವಿಲ್ಲದ ಎಲ್ಲಾ\nಕರ್ಮಗಳು. ಸೇರಿದರೂ ಅದು ಜ್ಞಾನಪೂರ್ಣ ಕರ್ಮದ ಮುಂದೆ ಅತ್ಯಲ್ಪ. ನಮ್ಮ ಕರ್ಮ\nಜ್ಞಾನಕ್ಕೋಸ್ಕರವಾಗಬೇಕೇ ಹೊರತು ಕರ್ಮಕ್ಕೋಸ್ಕರ ಕರ್ಮ ಮಾಡಬಾರದು. ಆದರೆ ಇಂದಿನ ದಿನದಲ್ಲಿ\nಜ್ಞಾನಕ್ಕೋಸ್ಕರ ಕರ್ಮ ಮಾಡುವವರ ಸಂಖ್ಯೆ ಕಡಿಮೆಯಾಗುತ್ತಿರುವುದು ದುಃಖದಾಯಕ.\n\nಇಲ್ಲಿ ಕೃಷ್ಣ ಅರ್ಜುನನನ್ನು \"“ಪಾರ್ಥಾ' ಎಂದು ಸಂಬೋಧಿಸಿದ್ದಾನೆ. ಹಿಂದೆ ಹೇಳಿದಂತೆ ಪಾರ್ಥ ಎಂದರೆ\nಪಾರವನ್ನು ಕಂಡವನು, ಜ್ಞಾನದ ಕಡಲಿನ ಆಚೆಯ ದಡವನ್ನು ಕಂಡವನು; ವೇದಾರ್ಥವನ್ನು ಪಾನ\nಮಾಡಿದವನು. \"ಮಹಾನ್‌ ಜ್ಞಾನಿಯಾದ ನೀನು ಅರಿತು ಮಾಡುವ ಈ ಕರ್ಮ ಕೇವಲ ಕರ್ಮವಲ್ಲ ಇದು\nಜ್ಞಾನಯಜ್ಞ” ಎನ್ನುವ ಧ್ವನಿ ಈ ಸಂಬೋಧನೆಯಲ್ಲಿದೆ. ಇಲ್ಲಿ ನಾವು ಪುನಃ ನೆನಪಿಸಿಕೊಳ್ಳಬೇಕಾದ ವಿಷಯ\nಎಂದರೆ ಮೂಲತಃ ಅರ್ಜುನ ಮಹಾನ್‌ ಜ್ಞಾನಿ. ಆದರೆ ಮಹಾನ್‌ ಜ್ಞಾನಿಗಳಿಗೂ ಕೂಡಾ ಕೆಲವೊಮ್ಮೆ\nಗೊಂದಲವಾಗಿ ಎಲ್ಲವೂ ಮರೆತು ಹೋಗುತ್ತದೆ. ಅರ್ಜುನ ಇಲ್ಲಿ ಆ ಸ್ಥಿತಿಯಲ್ಲಿದ್ದಾನೆ. ಇದು ಕೇವಲ ತಾತ್ಕಾಲಿಕ\nಪರದೆ, ಆ ಪರದೆಯನ್ನು ಕೃಷ್ಣ ಸರಿಸುತ್ತಿದ್ದಾನೆ.\n\nಜ್ಞಾನವಿಲ್ಲದ ಕರ್ಮದಿಂದ ಯಾವ ಉಪಯೋಗವೂ ಇಲ್ಲ ಅನ್ನು ವ ವಿಚಾರ ಸ್ಟ ಷ್ಟ ವಾಯಿತು. ಆದರೆ ಈ\nಜ್ಞಾನವನ್ನು ಗಳಿಸುವ ಪರಿ ಎಂತು? ಈ ಪ್ರಶ್ನೆ ಗೆ ಕೃಷ್ಣ ಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ಉತ್ತರಿಸುತ್ತಾನೆ.\n",
  "4.34": "ತತ್ ವಿದ್ಧಿ ಪ್ರಣಿಪಾತೇನ ಪರಿಪ್ರಶ್ನೇನ ಸೇವಯಾ |\nಉಪದೇಕ್ಷ್ಯಂತಿ ತೇ ಜ್ಞಾನಮ್ ಜ್ಞಾನಿನಃ ತತ್ತ್ವದರ್ಶಿನಃ -- ಜ್ಞಾನವನ್ನು ಗಳಿಸಬೇಕಾದರೆ \"ನೀನು ಜ್ಞಾನಿಗಳ ಬೆನ್ನುಹತ್ತಬೇಕು; ಸತ್ಯವನ್ನು ಸಾಕ್ಷಾತ್ಕಾರ ಮಾಡಿಕೊಂಡ ತತ್ತ್ವದರ್ಶಿಗಳಿಂದ ಜ್ಞಾನವನ್ನು ಪಡೆ\" ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಜ್ಞಾನ ಎನ್ನುವುದು ಕೇವಲ ಪುಸ್ತಕವನ್ನು ಓದುವುದರಿಂದ ಬರುವುದಲ್ಲ. ಅದು ನಮಗೆ ಸಾಕ್ಷಾತ್ಕಾರವಾಗಬೇಕು. \"Truth is an intuitional flash, it is not Intellectual\". ಸತ್ಯ ಎನ್ನುವುದು ನಮಗೆ ಸ್ಫುರಣವಾಗಬೇಕು.\n\nಸಾಮಾನ್ಯವಾಗಿ ಸತ್ಯವನ್ನು ಸಾಕ್ಷಾತ್ಕಾರ ಮಾಡಿಕೊಂಡ ಜ್ಞಾನಿಗಳು ಜ್ಞಾನವನ್ನು ಯೋಗ್ಯರಲ್ಲದವರಿಗೆ ಎಂದೂ ಬೋಧಿಸುವುದಿಲ್ಲ. ಈ ಕಾರಣಕ್ಕಾಗಿ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: \"ತತ್ತ್ವದರ್ಶಿಗಳನ್ನು ಕಂಡರೆ ಬಿಡಬೇಡ, ಅವರ ಬೆನ್ನು ಹತ್ತು, ಅವರನ್ನು ಒಲಿಸಿಕೋ, ಅವರ ಮುಂದೆ ನೀನು ಯೋಗ್ಯ ಎಂದು ರುಜುವಾತು ಪಡಿಸು. ನಿನ್ನ ಅನನ್ಯ ಬಯಕೆ ಅವರಿಗೆ ಮನವರಿಕೆಯಾಗುವಂತೆ ಮಾಡು, ಅವರಿಗೆ ಶರಣಾಗು\" ಎಂದು.",
  "4.35": "ತತ್‌ ವಿದ್ಧಿ ಪ್ರಣಿಪಾತೇನ ಪರಿಪ್ರಶ್ನೇನ ಸೇವಯಾ |\n\nಉಪದೇಕ್ಷ್ಯಂತಿ ತೇ ಜ್ಞಾನಮ್‌ ಜ್ಞಾನಿನಃ ತತ್ತ್ವದರ್ಶಿನಃ ॥\n\nಯತ್‌ ಜ್ಞಾತ್ವಾ ನ ಪುನಃ ಮೋಹಮ್‌ ಏವಮ್‌ ಯಾಸ್ಯಸಿ ಪಾಂಡವ |\n\nಯೇನ ಭೂತಾನಿ ಅಶೇಷೇಣ ದ್ರಕ್ಷ್ಯಸಿ ಆತ್ಮನಿ ಅಥ ಉ ಮಯಿ -- ಪಾಂಡವಾ, ಯಾವುದನ್ನು ತಿಳಿದಾಗ\nನೀನು ಮತ್ತೆ ಹೀಗೆ ಮೋಹಗೊಳ್ಳುವುದಿಲ್ಲವೋ; ಯಾವ ಮೋಹವಳಿದದ್ದರಿಂದ ಎಲ್ಲಾ ಜೀವಿಗಳನ್ನು\nಅಂತರ್ಯಾಮಿಯಾದ ([ಎಲ್ಗೆಲ್ಲೂ ಇರುವ] ನನ್ನಲ್ಲಿ ಕಾಣಬಲ್ಲೆಯೋ, ಅಂತಹ ತಿಳಿವನ್ನು ನಿಜ ಕಂಡು ತಿಳಿದವರು\nನಿನಗೆ ತಿಳಿಹೇಳುತ್ತಾರೆ. ಕಾಲಿಗೆರಗಿ, ಪರಿಪರಿಯಿಂದ ಕೇಳಿ, ಸೇವೆಗೈದು ಅದನ್ನು ತಿಳಿದುಕೋ.\n\nಜ್ಞಾನವನ್ನು ಗಳಿಸಬೇಕಾದರೆ \"ನೀನು ಜ್ಞಾನಿಗಳ ಬೆನ್ನುಹತ್ತಬೇಕು; ಸತ್ಯವನ್ನು ಸಾಕ್ಷಾತ್ಕಾರ ಮಾಡಿಕೊಂಡ\nತತ್ವದರ್ಶಿಗಳಿಂದ ಜ್ಞಾನವನ್ನು ಪಡೆ ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಜ್ಞಾನ ಎನ್ನುವುದು ಕೇವಲ ಪುಸ್ತಕವನ್ನು ಓದುವುದರಿಂದ\nಬರುವುದಲ್ಲ. ಅದು ನಮಗೆ ಸಾಕ್ಷಾತ್ಕಾರವಾಗಬೇಕು. “Truth is an intuitional flash, it is not Intellectual”. ಸತ್ಯ ಎನ್ನುವುದು ನಮಗೆ ಸ್ಟುರಣವಾಗಬೇಕು. ಎಲ್ಲಾ ವೇದ ಮಂತ್ರಗಳೂ ಋಷಿಗಳಿಗೆ\nಅಂತರಂಗದಲ್ಲಿ ಸ್ಟೂರಣವಾಗಿರುವುದು. ನ್ಯೂಟನ್‌ ಗೆ ಗುರುತ್ವಾಕರ್ಷಣ ಶಕ್ತಿಯ\nವಿಚಾರ ಹೊಳೆದಂತೆ. ಈ ಕಾರಣಕ್ಕಾಗಿ ಮೊದಲು ನಾವು ಸತ್ಯಕ್ಕೆ ಶರಣಾಗಬೇಕು; ಸತ್ಯವನ್ನು ಕಂಡ\nತತ್ವಜ್ಞಾನಿಗಳ ಬೆನ್ನುಹತ್ತಬೇಕು.\n\nಸಾಮಾನ್ಯವಾಗಿ ಸತ್ಯವನ್ನು ಸಾಕ್ಷಾತ್ಕಾರ ಮಾಡಿಕೊಂಡ ಜ್ಞಾನಿಗಳು ಜ್ಞಾನವನ್ನು ಯೋಗ್ಯರಲ್ಲದವರಿಗೆ ಎಂದೂ\nಬೋಧಿಸುವುದಿಲ್ಲ. ಈ ಕಾರಣಕ್ಕಾಗಿ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: \"ತತ್ವದರ್ಶಿಗಳನ್ನು ಕಂಡರೆ ಬಿಡಬೇಡ, ಅವರ ಬೆನ್ನು\nಹತ್ತು, ಅವರನ್ನು ಒಲಿಸಿಕೋ, ಅವರ ಮುಂದೆ ನೀನು ಯೋಗ್ಯ ಎಂದು ರುಜುವಾತು ಪಡಿಸು. ನಿನ್ನ ಅನನ್ಯ\nಬಯಕೆ ಅವರಿಗೆ ಮನವರಿಕೆಯಾಗುವಂತೆ ಮಾಡು, ಅವರಿಗೆ ಶರಣಾಗು\" ಎಂದು. ಇಲ್ಲಿ 'ಪ್ರಣಿಪಾತ' ಅಂದರೆ\nಎಂಟು ಅಂಗಗಳ ನಮಸ್ಕಾರ. ತಲೆ, ಎದೆ, ಕೈ, ಕಾಲು ಎಲ್ಲವನ್ನು ನೆಲಕ್ಕೆ ತಾಗಿಸಿ, ಭಕ್ತಿಯ ದೃಷ್ಟಿಯಿಂದ,\nಸ್ತೋತ್ರ(ವಚನ) ಮುಖೇನ, ಮನಸ್ಸಿನಲ್ಲಿ ಅಪಾರ ಗೌರವವಿಟ್ಟು ಮಾಡುವ ನಮಸ್ಕಾರ-'ಅಷ್ಟಾಂಗ ನಮನ\".\nಹೀಗೆ ಶರಣಾಗಿ “ಕೆದಕಿ ಕೆದಕಿ, ಪರಿಪರಿಯಾಗಿ ಕೇಳಿ ತಿಳಿದುಕೋ\" ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. 'ತತ್ವದರ್ಶಿಗಳ\n\nಸೇವೆಮಾಡಿ ಅವರಿಂದ ಜ್ಞಾನವನ್ನು ಗಳಿಸು, ಅದರಿಂದ ಕರ್ಮ ಮಾಡು' ಎನ್ನುವುದು ಕೃಷ್ಣ ಅರ್ಜುನನ ಮೂಲಕ\nನಮಗೆ ಕೊಟ್ಟ ಸಂದೇಶ.\n\nಒಮ್ಮೆ ತತ್ವದರ್ಶಿಗಳಿಂದ ಜ್ಞಾನವನ್ನು ಪಡೆದರೆ ಮುಂದೆ ಮೋಹಕ್ಕೆ ಅವಕಾಶವಿಲ್ಲ. ಇಲ್ಲಿ ಅರ್ಜುನನನ್ನು\nಕಾಡುತ್ತಿರುವುದು ಜ್ಞಾನವನ್ನು ಮುಚ್ಚಿರುವ ಮೋಹದ ಪರದೆ. ಅದಕ್ಕಾಗಿ ಕೃಷ್ಣ ಅರ್ಜುನನನ್ನು 'ಪಾಂಡವ' ಎಂದು\nಸಂಬೋಧಿಸುತ್ತಾನೆ. ಇಲ್ಲಿ 'ಪಂಡಾ' ಎಂದರೆ ಜ್ಞಾನ (ಉದಾ:ಪಂಡಾ ಉಳ್ಳವ ಪಂಡಿತ), ಪಾಂಡವ ಎಂದರೆ\nಜ್ಞಾನರಾಶಿಯನ್ನು ಪಡೆದವ. ಇನ್ನು ಪಾಂಡು ಎಂದರೆ 'ಬಿಳಿ ಬಣ್ಣ'. ಅದು ಸಾತ್ವಿಕತೆಯ ಸಂಕೇತ. 'ನೀನು ಸ್ವಯಂ\nಜ್ಞಾನಿ ಹಾಗೂ ಸಾತ್ವಿಕ' ಎಂದು ಸೂಚಿಸಿ ಇಲ್ಲಿ ಈ ಸಂಬೋಧನೆ.\n\nಒಮ್ಮೆ ಸತ್ಯದ ಅರಿವು ಬಂದರೆ ಅದರಿಂದ ಮೋಹದ ಪಾಶ ಕಳಚಿಹೋಗುತ್ತದೆ. ಅದು ಪುನಃ ಬರುವ\nಸಂಭವವಿಲ್ಲ. ಈ ಸ್ಥಿತಿಯಲ್ಲಿ ಸಮಸ್ತ ಜೀವಜಾತವೂ ಆತ್ಮನಲ್ಲಿ (ಭಗವಂತನಲ್ಲಿ) ಆಶ್ರಿತವಾಗಿದೆ, ಎಲ್ಲವುದಕ್ಕೂ\nನಿಯಾಮಶಶಕ್ತಿ ಭಗವಂತ ಎನ್ನುವ ಪ್ರಜ್ಞೆ ಜಾಗೃತವಾಗುತ್ತದೆ. ಇದರಿಂದ ಎಲ್ಲಾ ಗೊಂದಲವೂ\nಮರೆಯಾಗುತ್ತದೆ. ಸ್ವಾರ್ಥ, ದುಃಖ, ಅಸೂಹೆ, ಎಲ್ಲವೂ ಹೊರಟು ಹೋಗಿ ಸ್ಥಿತಪ್ರಜ್ಞೆ ಮೂಡುತ್ತದೆ. ಭಗವಂತ\nಅಣು ಒಳಗೆ ಅಣುವಾಗಿ, ಎಲ್ಲರೊಳಗೂ ಬಿಂಬ ರೂಪನಾಗಿ ತುಂಬಿದ್ದಾನೆ ಹಾಗೂ ಆತ ಮಹತ್ತಿನಲ್ಲಿ\nಮಹತ್ತಾಗಿರುವ ಸರ್ವಗತ. ಅವನ ಇಚ್ಛೆಯಂತೇ ಎಲ್ಲವೂ ನಡೆಯುತ್ತದೆ ಎನ್ನುವ ಸತ್ಯ ತಿಳಿಯುತ್ತದೆ.\nಭಗವಂತನಲ್ಲಿ ತನ್ನನ್ನು ತಾನು ಒಪ್ಪಿಸಿಕೊಂಡವನಿಗೆ ಜೀವನದಲ್ಲಿ ಎಂದೂ ಭಯವಿಲ್ಲ.\n\nಜ್ಞಾನದಿಂದ ಕರ್ಮ ಮಾಡಬೇಕು, ತತ್ವ ಜ್ಞಾನಿಗಳಿಂದ ಜ್ಞಾನ ಪಡೆಯಬೇಕು, ಅದರಿಂದ ಮೋಕ್ಷ ಸಾಧ್ಯ ಎನ್ನುವ\nವಿಚಾರ ತಿಳಿಯಿತು. ಆದರೆ ಈ ವಿಷಯ ತಿಳಿಯುವ ಮೊದಲು ಸಾಕಷ್ಟು ಪಾಪ ಕರ್ಮಗಳನ್ನು ಮಾಡಿದ ಪಾಪಿಗಳ\nಗತಿ ಏನು? ಇದಕ್ಕಾಗಿ ಭಯ ಪಡಬೇಕಾಗಿಲ್ಲ ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಈ ವಿಚಾರವಾಗಿ ಕೃಷ್ಣನ ಭರವಸೆಯನ್ನು\nಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ನೋಡೋಣ.",
  "4.36": "ಅಪಿ ಚೇತ್‌ ಅಸಿ ಪಾಪೇಭ್ಯಃ ಸರ್ವೇಭ್ಯಃ ಪಾಪ ಕೃತ್‌ ತಮಃ\nಸರ್ವಮ್‌ ಜ್ಞಾನ ಪ್ಲವೇನ ಏವ ವೃಜಿನಮ್‌ ಸಂತರಿಷ್ಯಸಿ-ನೀನು ಎಲ್ಲಾ ಪಾಪಿಗಳಿಗಿಂತಲೂ ಹಿರಿಯ\nಪಾಪಿಯಾಗಿದ್ದರೂ ಸರಿಯೇ, ಎಲ್ಲಾ ಪಾತಕಗಳನ್ನೂ ತಿಳಿವಿನ ದೋಣಿಯಿಂದ ದಾಟಬಲ್ಲೆ.\n\n\"ನೀನು ನಿನ್ನ ಕಾಲದಲ್ಲಿನ ಸರ್ವಶ್ರೇಷ್ಠ ಪಾಪಿಯಾಗಿದ್ದರೂ ಕೂಡಾ, ಒಮ್ಮೆ ನಿನಗೆ ಭಗವಂತನ ಅರಿವು\nಮೂಡಿದರೆ ನೀನು ಗೆದ್ದಂತೆ\" ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಏಕೆಂದರೆ ತಿಳುವಳಿಕೆ ಬಂದ ಮೇಲೆ ಜ್ಞಾನದ ಮಾರ್ಗದಲ್ಲಿ\nಸಾಗಿದರೆ ಹಿಂದಿನ ಯಾವ ಪಾಪವೂ ನಿಲ್ಲುವುದಿಲ್ಲ. ಜ್ಞಾನವೆನ್ನುವುದು ಪಾಪದ ಕಡಲಿನಲ್ಲಿ ದೋಣಿಯಂತೆ. ಅದು\nನಮ್ಮನ್ನು ದಡ ಸೇರಿಸಬಲ್ಲದು. ಪಾಪದ ಕಡಲನ್ನು ದಾಟಲು ಇರುವ ಒಂದೇ ಒಂದು ಸಾಧನ ಜ್ಞಾನ. ಇಂತಹ\n\nದೊಡ್ಡ ಭರವಸೆಯನ್ನು ಕೃಷ್ಣ ಕೊಟ್ಟಿದ್ದಾನೆ. ಆದ್ದರಿಂದ ನಾವೆಲ್ಲರೂ ಇಂದೇ ಈ ಕ್ಷಣದಿಂದ ಜ್ಞಾನ ಮಾರ್ಗದಲ್ಲಿ\nಸಾಗುವ ಸಂಕಲ್ಪ ತೊಟ್ಟು ಮುಂದುವರಿಯೋಣ- ಏಕೆಂದರೆ ನಾಳೆ ಎಂದರೆ ಆ ನಾಳೆ ನಮ್ಮ ಪಾಲಿಗೆ ಬಾರದೇ\nಇರಬಹುದು!\n\nಜ್ಞಾನ ಮಾರ್ಗವನ್ನು ಹಿಡಿದ ಒಬ್ಬ ಪಾಪಿಯ ಪಾಪಕರ್ಮವೇನಾಗುತ್ತದೆ ಎನ್ನುವುದಕ್ಕೆ ಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ\nಕೃಷ್ಣ ವಿವರಣೆಯನ್ನು ಕೊಟ್ಟಿದ್ದಾನೆ.",
  "4.37": "ಯಥಾ ಏಧಾಂಸಿ ಸಮಿದ್ಧಃ ಅಗ್ನಿಃ ಭಸ್ಮ ಸಾತ್‌ ಕುರುತೇ ಅರ್ಜುನ |\nಜ್ಞಾನಾಗ್ನಿಃ ಸರ್ವ ಕರ್ಮಾಣಿ ಭಸ್ಮ ಸಾತ್‌ ಕುರುತೇ ತಥಾ- ಅರ್ಜನಾ, ಉರಿಯುವ ಬೆಂಕಿ\nಉರುವಲನ್ನುಸುಟ್ಟುಬಿಡುವ ಹಾಗೆ ಅರಿವಿನ ಬೆಂಕಿ ಎಲ್ಲಾ ಕರ್ಮಗಳನ್ನೂ ಸುಟ್ಟುಬಿಡುತ್ತದೆ.\n\nಜ್ಞಾನ ಎನ್ನುವುದು ಸದಾ ಪ್ರಜ್ವಲಿಸುವ ಬೆಂಕಿ. ಅದಕ್ಕಿಂತ ಹೆಚ್ಚು ಶಕ್ತಿ ಶಾಲಿಯಾದ ಬೆಂಕಿ ಇನ್ನೊಂದಿಲ್ಲ. ಹೇಗೆ\nಉರಿಯುವ ಬೆಂಕಿ ಕಟ್ಟಿಗೆಯನ್ನು ಸುಟ್ಟುಬಿಡುತ್ತದೋ, ಹಾಗೇ ಜ್ಞಾನದ ಬೆಂಕಿ ಎಲ್ಲಾ ಪಾಪ ಕರ್ಮವನ್ನು\nಸುಟ್ಟುಬಿಡುತ್ತದೆ. ಭಾಗವತದಲ್ಲಿ ಹೇಳುವಂತೆ ಆಧ್ಯಾತ್ಮಿಕವಾಗಿ ಬೆಂಕಿ ಸತ್ವ ಗುಣದ ಪ್ರತೀಕ. ಏಕೆಂದರೆ ಅದು\nಬೆಳಕು ಕೊಡುವ ಹಾಗೂ ಸದಾ ಊರ್ಧ್ವ ಮುಖವಾಗಿರುವ ಶಕ್ತಿ. ಅದೇ ರೀತಿ ಕಟ್ಟಿಗೆ ಸದಾ ಕೆಳಕ್ಕೆಳೆಯುವ\nತಮೋಗುಣದ ಪ್ರತೀಕ... ಬೆಂಕಿ ಕಟ್ಟಿಗೆಯನ್ನು ಸುಟ್ಟಂತೆ ಒಬ್ಬ ಸಾಧಕನಲ್ಲಿರುವ ಜ್ಞಾನ ತಮಸ್ಸನ್ನು\nಸುಟ್ಟುಬಿಡುತ್ತದೆ. ಇಲ್ಲಿ ಕೃಷ್ಣ \"ಅರ್ಜುನಾ' ಎಂದು ಸಂಬೋಧಿಸಿದ್ದಾನೆ. ಅರ್ಜುನ ಎಂದರೆ “ಅರ್ಜನ' ಮಾಡಿದವ,\nಜ್ಞಾನವೆಂಬ ಬೆಂಕಿ ಉಳ್ಳವ. ಈ ಸಂಬೋಧನೆಯಿಂದ ಕೃಷ್ಣ ಅರ್ಜುನನ ಜ್ಞಾನಕ್ಕೆ ಆವರಿಸಿರುವ ಮೋಹದ\nಪರದೆಯನ್ನು ಸರಿಸುತ್ತಿದ್ದಾನೆ.\n",
  "4.38": "ನಹಿ ಜ್ಞಾನೇನ ಸದೃಶಮ್‌ ಪವಿತ್ರಮ್‌ ಇಹ ವಿದ್ಯತೇ\nತತ್‌ ಸ್ವಯಮ್‌ ಯೋಗ ಸಂಸಿದ್ಧಃ ಕಾಲೇನ ಆತ್ಮನಿ ವಿಂದತಿ- ತಿಳಿವಿಗೆ ಸಾಟಿಯಾದ ಪಾವನವಾದ ವಸ್ತು ಇಲ್ಲಿ\nಇನ್ನೊಂದಿಲ್ಲ. ಸಾಧನೆಯಿಂದ ಪಳಗಿದವನು ತಕ್ಕ ಕಾಲದಲ್ಲಿ ಅದನ್ನು ತಾನೇ ತನ್ನಲ್ಲಿ ಪಡೆಯುತ್ತಾನೆ.\n\nಜ್ಞಾನ ಎನ್ನುವುದು ಮಹಾಪವಿತ್ರ. ಅದಕ್ಕೆ ಸಾಟಿಯಾದ ಇನ್ನೊಂದು ವಸ್ತು ಈ ಪ್ರಪಂಚದಲ್ಲಿಲ್ಲ. ಏಕೆಂದರೆ\nಜ್ಞಾನವೆಂದರೆ ಭಗವಂತ. ಆದ್ದರಿಂದ \"ಜ್ಞಾನ ಮಾರ್ಗವನ್ನು ಹಿಡಿ, ಕಾಲ ಪರಿಪಕ್ಚವಾದಾಗ ನೀನು ಸಿದ್ಧಿಯನ್ನು\nಪಡೆದೇ ಪಡೆಯುತ್ತೀ” ಎನ್ನುವುದು ಕೃಷ್ಣನ ಭರವಸೆ. ಕೆಲವೊಮ್ಮೆ ಸಾಧನೆಯ ಪಥದಲ್ಲಿ ಸಿದ್ಧಿಯನ್ನು ಪಡೆಯಲು\nಕೆಲವು ಜನ್ಮಗಳೇ ಬೇಕಾಗಬಹುದು. ಆದರೆ ಭಗವಂತನ ಭರವಸೆಯನ್ನು ನಂಬಿ ಆತ್ಮವಿಶ್ವಾಸದಿಂದ\nಮುನ್ನೆಡೆದವನು ಸಿದ್ಧಿಯನ್ನು ಪಡೆಯುತ್ತಾನೆ.\n",
  "4.39": "ಶ್ರದ್ಧಾವಾನ್‌ ಲಭತೇ ಜ್ಞಾನಮ್‌ ತತ್‌ ಪರಃ ಸಂಯತ ಇಂದ್ರಿಯಃ ।\n\nಜ್ಞಾನಮ್‌ ಲಬ್ಧ್ವಾ ಪರಾಮ್‌ ಶಾಂತಿಮ ಆಚಿರೇಣ ಅಧಿಗಚ್ಛತಿ-- ಇಂದ್ರಿಯಗಳನ್ನು ಹದ್ದಿನಲ್ಲಿಟ್ಟು ಸ; ಶ್ರದ್ಧೆಯಿಂದ\nನನ್ನನ್ನೇ ಪರದೈವವೆಂದು ನಂಬಿದವನು ತಿಳಿವನ್ನುಗಳಿಸಿ ಶೀಘ್ರವಾಗಿ ಸಂತಸದ ಸೆಲೆಯಾದ ಮುಕ್ತಿಯನ್ನು\nಪಡೆಯುತ್ತಾನೆ.\n\nನಮ್ಮಲ್ಲಿ ಅರಿವು. ಮೂಡಬೇಕೆಂದರೆ. ಬರಿಯ ಅಧ್ಯಯನ ಸಾಲದು. ಒಂದು ವಿಷಯ ನಮಗೆ\nಮನವರಿಕೆಯಾಗಬೇಕಾದರೆ ಮೊದಲು ನಮಗೆ ಶ್ರದ್ಧೆ ಬೇಕು. ಇಲ್ಲಿ ಸಮರ್ಪಣಾ ಭಾವನೆ ಅತಿಮುಖ್ಯ. ನಾನು\nತಿಳಿದದ್ದೇ ದೊಡ್ಡದು, ಅದಕ್ಕಿಂತ ದೊಡ್ಡದು ಯಾವುದೂ ಇಲ್ಲ ಅನ್ನುವ ಅಹಂಕಾರವನ್ನು ಮೊದಲು ಬಿಡಬೇಕು.\nನನಗೆ ಯಾವುದು ತಿಳಿದಿಲ್ಲವೋ ಅದು ಸತ್ಯವಾಗಿರಲು ಸಾಧ್ಯ ಎನ್ನುವ ಶ್ರದ್ಧೆ ಬೇಕು. ಪ್ರಪಂಚದ ಸತ್ಯ ನಮ್ಮ\nನಂಬಿಕೆಯ ಮೇಲೆ ನಿಂತಿಲ್ಲ. ಈ ಪ್ರಪಂಚದಲ್ಲಿ ನಮಗೆ ತಿಳಿದಿರುವುದು ಕೇವಲ ಅತೀ ಚಿಕ್ಕ ಅಂಶ. ನಮಗೆ\nಗೊತ್ತಿಲ್ಲದೇ ಇರುವ ಸತ್ಯ ಇದೆ ಎಂದು ತಿಳಿಯುವುದೇ ಶ್ರದ್ಧೆ. ನಮ್ಮ ಬದುಕಿನ ಗುರಿ ಜ್ಞಾನ ಮತ್ತು ಸತ್ಯದ\nತಿಳುವಳಿಕೆಯಾಗಬೇಕು. ಜ್ಞಾನದ ತೃಷೆ ಜೊತೆಗೆ ಇಂದ್ರಿಯಗಳ ಚಾಪಲ್ಯಕ್ಕೆ ಹಿಡಿತವಿರಬೇಕು. ಹೀಗಿದ್ದಾಗ\nಅದರಿಂದ ಮಾನಸ ಸಾಕ್ಷಾತ್ಕಾರ, ಆತ್ಮಸಾಕ್ಷಾತ್ಕಾರ-ಕೊನೆಗೆ ಪರಮಾತ್ಮನ ಸಾಕ್ಷಾತ್ಕಾರ. ಈ ನಡೆಯಿಂದ\nಅಪರೋಕ್ಷ ಜ್ಞಾನ ಸಿದ್ಧಿಯಾಗುತ್ತದೆ. ಮತ್ತು ಇದರಿಂದ ಸದಾ ಜ್ಞಾನಾನಂದಪೂರ್ಣನಾದ ಭಗವಂತನನ್ನು\n(ಮೋಕ್ಷವನ್ನು) ಪಡೆಯಲು ಸಾಧ್ಯ.\n",
  "4.40": "ಅಜ್ಞಃ ಚ ಅಶ್ರದ್ದಧಾನಃ ಚ ಸಂಶಯ ಆತ್ಮಾ ವಿನಶ್ಯತಿ\nನ ಅಯಮ್‌ ಲೋಕಃ ಅಸ್ತಿ ನ ಪರಃ ನ ಸುಖಮ್‌ ಸಂಶಯ ಆತ್ಮನಃ -- ಅರಿವಿರದ, ನಂಬಿಕೆ ಕಳೆದುಕೊಂಡ\nಇಬ್ಬಂದಿ ವಿನಾಶದತ್ತ ಸಾಗುತ್ತಾನೆ. ಇಬ್ಬಂದಿಗೆ ಇಹವಿಲ್ಲ; ಪರವಿಲ್ಲ; ನೆಮ್ಮದಿಯೂ ಇಲ್ಲ.\n\nಜ್ಞಾನವಿಲ್ಲದ, ಶ್ರದ್ಧೆ ಇಲ್ಲದ ಅಜ್ಞಾನಿಗಳು ನಿರಂತರ ಸಂಶಯದಲ್ಲೇ ಬದುಕುತ್ತಾರೆ. ಜ್ಞಾನ ಮತ್ತು ಶ್ರದ್ಧೆ ಇಲ್ಲದಾಗ\nಅಲ್ಲಿ ಸಂಶಯ ಬೆಳೆಯಲಾರಂಭಿಸುತ್ತದೆ. ಆ ಸಂಶಯ ಮನಸ್ಸನ್ನು ಆಕ್ರಮಿಸಿ ನಂತರ ಚಿತ್ತವನ್ನು ತಲುಪುತ್ತದೆ.\nಬುದ್ಧಿಗೆ ಬಂದ ಸಂಶಯಕ್ಕೆ ಪರಿಹಾರವಿಲ್ಲ. ಅದು ನಮ್ಮನ್ನು ಅಧಃಪಾತಕ್ಕೆ ಕೊಂಡೊಯ್ಯುತ್ತದೆ. ಇದರಿಂದ\nಅಂತವರಿಗೆ ಇಹವಿಲ್ಲ, ಪರವಿಲ್ಲ, ಎಂದೆಂದೂ ನೆಮ್ಮದಿ ಇಲ್ಲ.\n",
  "4.41": "ಯೋಗ ಸಂನ್ಯಸ್ತ ಕರ್ಮಾಣಮ್‌ ಜ್ಞಾನ ಸಂಛಿನ್ನ ಸಂಶಯಮ್‌\nಆತ್ಮವಂತಮ್‌ ನ ಕರ್ಮಾಣಿ ನಿಬಧ್ದಂತಿ ಧನಂಜಯ- ಧನಂಜಯಾ, ಸಾಧನೆಯಿಂದ ಕರ್ಮಫಲದ ನಂಟು\nತೊರೆದ, ಅರಿವಿನಿಂದ ಶಂಕೆಗಳನ್ನು ಕಳೆದುಕೊಂಡ ಭಗವದ್ಭ್‌ ಕ್ತನನ್ನು ಕರ್ಮಗಳು ಕಟ್ಟಿ ಹಾಕುವುದಿಲ್ಲ.\n\nಜೀವನದಲ್ಲಿ ಕರ್ಮ ಮಾಡು, ಕರ್ಮ ಮಾಡುತ್ತಾ ಕರ್ಮ ಸಂನ್ಯಾಸ ಮಾಡು ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಇಲ್ಲಿ ಕರ್ಮ\nಸಂನ್ಯಾಸ ಅಂದರೆ ಕರ್ಮ ತ್ಯಾಗವಲ್ಲ. 'ಈ ಕರ್ಮ ಭಗವಂತನಿಗೆ ಸೇರಿದ್ದು ಎಂದು ಭಗವಂತನಲ್ಲಿ ಕರ್ಮವನ್ನು\nಅರ್ಪಿಸುವುದು'- ಕರ್ಮಸಂನ್ಯಾಸ(ಈ ಬಗ್ಗೆ ಮುಂದಿನ ಅಧ್ಯಾಯದಲ್ಲಿ ಹೆಚ್ಚಿನ ವಿವರಣೆಯನ್ನು ಕಾಣಬಹುದು).\nಕರ್ಮಫಲದ ಬಗ್ಗೆ ಆಸೆ ಆಕಾಂಕ್ಷೆಗಳನ್ನು ಬಿಟ್ಟು, ಎಲ್ಲವನ್ನೂ ಸಮದೃಷ್ಟಿಯಿಂದ ಕಾಣುತ್ತಾ, ನಿರ್ವಿಕಾರನಾಗಿ\nನಿರಂತರ ಕರ್ಮ ಮಾಡುವುದು ಕರ್ಮಸಂನ್ಯಾಸ. ಕರ್ಮವನ್ನು ಭಗವಂತನಲ್ಲಿ ಅರ್ಪಿಸಿ, ಜ್ಞಾನದಿಂದ\nಸಂಶಯವನ್ನು ಪರಿಹರಿಸಿಕೊಂಡು, ವಿವೇಕಿಯಾಗಿ ಚಿತ್ತವನ್ನು ಜಾಗೃತಿಗೊಳಿಸಿ, ಆತ್ಮವಂತನಾಗಿ\nಬದುಕುವುದನ್ನು ಕಲಿತಾಗ ಯಾವ ಕರ್ಮವೂ ಎಂದೂ ನಮಗೆ ಬಂಧಕವಾಗುವುದಿಲ್ಲ. \"ಯುದ್ಧದಲ್ಲಿ ಶತ್ರುಗಳನ್ನು\n\nಗೆದ್ದು ಧನವನ್ನು ಗೆದ್ದ ನೀನು, ಜ್ಞಾನಧನವನ್ನು ಗೆದ್ದ ಧನಂಜಯ, ನಿನ್ನನ್ನು ಕರ್ಮ ಬಂಧಿಸದು” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.",
  "4.42": "ತಸ್ಮಾತ್‌ ಅಜ್ಞಾನ ಸಂಭೂತಮ್‌ ಹೃತ್‌ ಸ್ಫಮ್‌ ಜ್ಞಾನ ಅಸಿನಾ ಆತ್ಮನಃ |\n\nಛಿತ್ವೈನಮ್‌ ಸಂಶಯಮ್‌ ಯೋಗಮ್‌ ಅತಿಷ್ಠ ಉತ್ತಿಷ್ಠ ಭಾರತ-ಆದ್ದರಿಂದ, ಓ ಭಾರತಾ, ಅಜ್ಞಾನದಿಂದ ಹುಟ್ಟಿ\nಬಗೆಯೊಳಹೊಕ್ಕು ನಿಂತ ನಿನ್ನ ಈ ಸಂದೇಹವನ್ನು ತಿಳಿವಿನ ಕತ್ತಿಯಿಂದ ಕತ್ತರಿಸಿ ಜ್ಞಾನದ ದಾರಿಯಲ್ಲಿ ನಡೆ;\nಎದು ನಿಲು.\n\n\"ಆದ್ದರಿಂದ ಎದ್ದು ನಿಲ್ಲು, ಭರತ ಚಕ್ರವರ್ತಿಯಂತಹ ಮಹಾ ಪುರುಷರು ಹುಟ್ಟಿ ಬಂದ ವಂಶದವನಾದ ನೀನು\nಜ್ಞಾನ ಸ್ವರೂಪನಾದ ಭಗವಂತನ ಭಕ್ತಿಯಲ್ಲಿ ನಿರತನಾದ ಜ್ಞಾನಿ(ಭಾರತ); ನಿನ್ನ ಮನಸ್ಸಿನಲ್ಲಿ ಕುಳಿತಿರುವ\n\nಸಂಶಯವನ್ನು ಭಗವಂತನೆನ್ನುವ ಜ್ಞಾನ ಕತ್ತಿಯಿಂದ ಕಡಿದು ಹಾಕು. ಅನ್ಯಾಯದ ವಿರುದ್ಧ ಹೋರಾಟ\n\nಭಗವಂತನ ಪೂಜೆ ಎನ್ನುವ ಧೀಕ್ಷೆ ತೊಟ್ಟು, ಸತ್ಯದ, ಪ್ರಾಮಾಣಿಕತೆಯ ಬದುಕನ್ನು ಬದುಕುವುದಕ್ಕೋಸ್ಕರ\nಪುಣ್ಯದ ಸಾಧನೆಯಲ್ಲಿ ತೊಡಗು” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.\n\nಇತಿ ಚತುರ್ಥೋ$ಧ್ಯಾಯಃ\nನಾಲ್ಕನೆಯ ಅಧ್ಯಾಯ ಮುಗಿಯಿತು.\n\nಅಧ್ಯಾಯ ಐದು\n\nನಾಲ್ಕನೇ ಅಧ್ಯಾಯದಲ್ಲಿ ಕೃಷ್ಣ ಕರ್ಮಯೋಗದ ಬಗ್ಗೆ ಹೇಳಿದ ಹಾಗೂ ಕೊನೆಯಲ್ಲಿ ಕರ್ಮಸಂನ್ಯಾಸದ ಬಗ್ಗೆಯೂ\nಹೇಳಿದ. ಇಲ್ಲಿ ನಮಗೆ ಸ್ವಲ್ಪ ಗೊಂದಲವಾಗುತ್ತದೆ. ಇದನ್ನು ಸಂಪೂರ್ಣ ಅರ್ಥ ಮಾಡಿಕೊಳ್ಳಬೇಕಾದರೆ ಮೊದಲು\nಕರ್ಮಯೋಗ ಮತ್ತು ಕರ್ಮಸಂನ್ಯಾಸ ಅಂದರೆ ಏನು ಎಂದು ತಿಳಿಯಬೇಕು. ಮೇಲ್ನೋಟಕ್ಕೆ ನಮಗೆ\n\nಕರ್ಮಸಂನ್ಯಾಸ ಅಂದರೆ 'ಕರ್ಮತ್ಯಾಗ' ಎನ್ನುವಂತೆ ಕಾಣುತ್ತದೆ. ಆದರೆ ಕೃಷ್ಣ ನಾಲ್ಕನೇ ಅಧ್ಯಾಯದ\nಕೊನೆಯಲ್ಲಿ \"ಎದ್ದು ನಿಲ್ಲು- ಯುದ್ಧ ಮಾಡು\" ಎಂದು ಅರ್ಜುನನನ್ನು ಕರ್ಮ ಮಾಡುವಂತೆ ಹುರಿದುಂಬಿಸಿದ್ದನ್ನು\nನಾವು ಕಂಡಿದ್ದೇವೆ. ಇದರಿಂದ ಕರ್ಮಸಂನ್ಯಾಸ ಅಂದರೆ ಕರ್ಮತ್ಯಾಗವಲ್ಲ ಎನ್ನುವುದು ನಮಗೆ\n\nಸ್ಟ ಷ್ಟವಾಗುತ್ತದೆ. ಶಾಸ್ತ್ರೀಯವಾಗಿ ಕರ್ಮಸಂನ್ಯಾಸ ಎಂದರೆ ದ್ವಂದ್ವಾತೀತವಾಗಿ, ಕರ್ಮಫಲದ\nಬಯಕೆಯಿಲ್ಲದೇ-ಕರ್ಮ ಮಾಡುವುದು. ಇಲ್ಲಿ ರಾಗ-ದ್ವೇಷಗಳಿಗೆ, ಕಾಮ-ಕ್ರೋಧಗಳಿಗೆ ಎಡೆಯಿಲ್ಲ. ಈ ಬಗ್ಗೆಯೂ\nವಿಶೇಷವಾಗಿ ಕೃಷ್ಣ ಹಿಂದೆ ವಿವರಿಸಿದ್ದ. ಆದ್ದರಿಂದ ಕರ್ಮಸಂನ್ಯಾಸ ಎಂದರೆ ಕರ್ಮವನ್ನು ಬಿಡುವುದಲ್ಲ,\nಕರ್ಮದಲ್ಲಿ ಕಾಮ ಕ್ರೋಧಗಳನ್ನು ಬಿಡುವುದು. \"ಕಾಮಕ್ರೋಧಗಳ ಅತೀತನಾಗಿ ಯುದ್ಧಮಾಡು ಮತ್ತು\nಜ್ಞಾನಯೋಗದ ದಾರಿಯಲ್ಲಿ ನಡೆ\" ಎನ್ನುವುದು ಅರ್ಜುನನಿಗೆ ಕೃಷ್ಣನ ಸಂದೇಶ. ಆದರೆ ಕಾಮ-ಕ್ರೋಧಗಳ\nಅತೀತನಾಗಿ ಜ್ಞಾನಮಾರ್ಗದಲ್ಲಿ ಯುದ್ಧ ಮಾಡುವುದು ಹೇಗೆ? ಇದನ್ನು. ಅರ್ಥ ಮಾಡಿಕೊಳ್ಳುವುದು ನಮಗೆ\nಸ್ವಲ್ಪ ಕಷ್ಟ. ಈ ಕುರಿತು ಅರ್ಜುನ ಕೃಷ್ಣನಲ್ಲಿ ವಿವರಣೆಯನ್ನು ನಮ್ಮ ನಿಮ್ಮೆಲ್ಲರ ಪರವಾಗಿ ಕೇಳುವುದರೊಂದಿಗೆ\nಐದನೇ ಅಧ್ಯಾಯ ಆರಂಭವಾಗುತ್ತದೆ. ಈ ಅಧ್ಯಾಯದಲ್ಲಿ ಕರ್ಮಸಂನ್ಯಾಸದ ಬಗ್ಗೆ ವಿಶೇಷವಾದ\n\nವಿವರಣೆಯನ್ನು ಕೃಷ್ಣ ನಮ್ಮ ಮುಂದಿಟ್ಟಿದ್ದಾನೆ.\n\nಅರ್ಜುನ ಉವಾಚ ।\nಸಂನ್ಯಾಸಂ ಕರ್ಮಣಾಂ ಕೃಷ್ಣ ಪುನರ್ಯೋಗಂ ಚ ಶಂಸಸಿ ।\n\nಯಚ್ಛ್ರೇಯ ಏತಯೋರೇಕಂ ತನ್ಮೇ ಬ್ರೂಹಿ ಸುನಿಶ್ಚಿತಮ್‌.. ॥೧॥\n\nಅರ್ಜುನಃ ಉವಾಚ-ಅರ್ಜುನ ಕೇಳಿದನು:\n\nಸಂನ್ಯಾಸಂ ಕರ್ಮಣಾಮ್‌ ಕೃಷ್ಣ ಪುನಃ ಯೋಗಮ್‌ ಚ ಶಂಸಸಿ |\n\nಯತ್‌ ಶ್ರೇಯಃ ಏತಯೋಃ ಏಕಮ್‌ ತತ್‌ ಮೇ ಬ್ರೂಹಿ ಸುನಿಶ್ಚಿತಮ್‌ -- ಕೃಷ್ಣಾ, ಒಮ್ಮೆ ಕರ್ಮಸಂನ್ಯಾಸವನ್ನು\nಹೊಗಳುತ್ತಿ; ಮತ್ತೊಮ್ಮೆ ಕರ್ಮಯೋಗವನ್ನು. ಇವೆರಡರಲ್ಲಿ ಯಾವುದು ಮಿಗಿಲು ಅದನ್ನು ನನಗೆ ಖಚಿತವಾಗಿ\nಹೇಳು.\n\nಅರ್ಜುನ ಕೇಳುತ್ತಾನೆ: \"ಓ ಕೃಷ್ಣಾ, ನೀನು ಒಮ್ಮೆ ಹೋರಾಡು ಎನ್ನು ತ್ತಿ ಇನ್ನೊ ಮ್ಮೆ ಕರ್ಮಸಂನ್ಯಾಸ ಮಾಡು\nಅನ್ನು ತ್ತಿ. ಒಂದು ವೇಳೆ ಕರ್ಮಸಂನ್ಯಾಸ ಅಂದರೆ ಕರ್ಮತ್ಯಾಗವಾದರೆ ಇದು ಒಂದಕ್ಕೊಂದು ವಿರುದ್ಧ. ಇದರಲ್ಲಿ\nಯಾವುದು ಶ್ರೇಯಸ್ಕರ ಎನ್ನು ವುದನ್ನು ನಿಶ್ಚಿತವಾಗಿ ಹೇಳು\" ಎಂದು. ಯುದ್ಧ ಮಾಡುವಾಗ ದ್ವಂದ್ವ ಅನ್ನುವುದು\n\nಇದ್ದೇ ಇದೆ. ದ್ವಂದ್ವತ್ಯಾಗದಿಂದ ಯುದ್ಧ ಮಾಡುವುದು ಹೇಗೆ? ಕರ್ಮಸಂನ್ಯಾಸ ಮತ್ತು ಕರ್ಮಯೋಗ ಇವೆರಡೂ\nಒಟ್ಟಿಗೆ ಹೇಗೆ ಸಾಧ್ಯ? ಯುದ್ಧವೆಂದಮೇಲೆ ರಾಗ-ದ್ವೇಷ ಇದ್ದೇ ಇರುತ್ತದೆ. ಈ ಕಾರಣದಿಂದ ಕೃಷ್ಣನ ಮಾತು\nನಮಗೆ ಖಚಿತವಾಗಿ ಅರ್ಥವಾಗುವುದಿಲ್ಲ. ಅದಕ್ಕಾಗಿ ಅರ್ಜುನ ಕೃಷ್ಣನಲ್ಲಿ ವಿವರವನ್ನು ಕೇಳುತ್ತಿದ್ದಾನೆ.\nಇಲ್ಲಿ ಅರ್ಜುನ ತನ್ನ ಪ್ರಶ್ನೆಯ ನಡುವೆ \"ಕೃಷ್ಣಾ\" ಎನ್ನುವ ಸಂಬೋಧನೆಯನ್ನು ಬಳಸಿದ್ದಾನೆ. 'ಕರ್ಷತಿ ಇತೀ\nಕೃಷ್ಣ. ಎಲ್ಲರನ್ನೂ ತನ್ನೆಡೆಗೆ ಸೆಳೆಯುವ ಪಾದರಸ, ಸಂಸಾರದಿಂದ ಎತ್ತರಕ್ಕೆ ಕೊಂಡೊಯ್ಯುವ\nಕರ್ಷಣಶಕ್ತಿಯಾದ ಸೌಂದರ್ಯಮೂರ್ತಿ ಭಗವಂತ ಕೃಷ್ಣಃ ಅಜ್ಞಾನದಿಂದ ಬರುವ ಸಂಶಯವನ್ನು\nಕರ್ಷಣೆಮಾಡಿ, ಜ್ಞಾನದ ಮಡಿಲಿಗೆ ಸೆಳೆಯುವ ನೀನು ನನಗೆ ಖಚಿತವಾಗಿ ಯಾವುದು ಶ್ರೇಯಸ್ಸು ಎನ್ನುವುದನ್ನು\nತಿಳಿಸು ಎನ್ನುವ ಭಾವ ಈ ಸಂಬೋಧನೆಯಲ್ಲಿದೆ.\nಭಗವಾನುವಾಚ ।\nಸಂನ್ಯಾಸಃ ಕರ್ಮಯೋಗಶ್ಚ ನಿಃಶ್ರೇಯಸಕರಾವುಭೌ ।\nತಯೋಸ್ತು ಕರ್ಮಸಂನ್ಯಾಸಾತ್‌ ಕರ್ಮಯೋಗೋ ವಿಶಿಷ್ಯತೇ ॥೨॥\n\nಭಗವಾನುವಾಚ- ಭಗವಂತ ಹೇಳಿದನು\n\nಸಂನ್ಯಾಸಃ ಕರ್ಮಯೋಗಃ ಚ ನಿಃಶ್ರೇಯಸ ಕರೌ ಉಭೌ |\n\nತಯೋಃ ತು ಕರ್ಮ ಸಂನ್ಯಾಸಾತ್‌ ಕರ್ಮಯೋಗಃ ವಿಶಿಷ್ಯತೇ -- ಕರ್ಮಸಂನ್ಯಾಸ ಮತ್ತು ಕರ್ಮಯೋಗ\nಎರಡೂ ಒಳಿತಿನ ದಾರಿಗಳೇ. ಅವುಗಳಲ್ಲಿ ಕರ್ಮಸಂನ್ಯಾಸಕ್ಕಿಂತ ಕರ್ಮಯೋಗ ಮಿಗಿಲು.\n\nಜ್ಞೇಯಃ ಸ ನಿತ್ಯಸಂನ್ಯಾಸೀಯೋ ನದ್ವೇಷ್ಟಿನ ಕಾಂಕ್ಷತಿ ।\nನಿರ್ದ್ವಂದ್ವೋ ಹಿ ಮಹಾಬಾಹೋ ಸುಖಂ ಬಂಧಾತ್‌ ಪ್ರಮುಚ್ಯತೇ ॥೩॥\n\nಜ್ಞೇಯಃ ಸ ನಿತ್ಯಸಂನ್ಯಾಸೀ ಯಃ ನದ್ವೇಷ್ಟಿನ ಕಾಂಕ್ಟತಿ ।\nನಿರ್ದ್ವಂದ್ವಃ ಹಿ ಮಹಾಬಾಹೋ ಸುಖಮ್‌ ಬಂಧಾತ್‌ ಪ್ರಮುಚ್ಯತೇ -- ದ್ವೇಷಿಸದವನು, ಮತ್ತು ಬಯಸದವನು\nನಿಜವಾದ ಸಂನ್ಯಾಸಿಯೆಂದರಿಯಬೇಕು. ಮಹಾವೀರಾ, ಇಂತಹ ದ್ವಂದ್",
  "5.1": "ಅರ್ಜುನ ಉವಾಚ ।\nಸಂನ್ಯಾಸಂ ಕರ್ಮಣಾಂ ಕೃಷ್ಣ ಪುನರ್ಯೋಗಂ ಚ ಶಂಸಸಿ ।\n\nಯಚ್ಛ್ರೇಯ ಏತಯೋರೇಕಂ ತನ್ಮೇ ಬ್ರೂಹಿ ಸುನಿಶ್ಚಿತಮ್‌.. ॥೧॥\n\nಅರ್ಜುನಃ ಉವಾಚ-ಅರ್ಜುನ ಕೇಳಿದನು:\n\nಸಂನ್ಯಾಸಂ ಕರ್ಮಣಾಮ್‌ ಕೃಷ್ಣ ಪುನಃ ಯೋಗಮ್‌ ಚ ಶಂಸಸಿ |\n\nಯತ್‌ ಶ್ರೇಯಃ ಏತಯೋಃ ಏಕಮ್‌ ತತ್‌ ಮೇ ಬ್ರೂಹಿ ಸುನಿಶ್ಚಿತಮ್‌ -- ಕೃಷ್ಣಾ, ಒಮ್ಮೆ ಕರ್ಮಸಂನ್ಯಾಸವನ್ನು\nಹೊಗಳುತ್ತಿ; ಮತ್ತೊಮ್ಮೆ ಕರ್ಮಯೋಗವನ್ನು. ಇವೆರಡರಲ್ಲಿ ಯಾವುದು ಮಿಗಿಲು ಅದನ್ನು ನನಗೆ ಖಚಿತವಾಗಿ\nಹೇಳು.\n\nಅರ್ಜುನ ಕೇಳುತ್ತಾನೆ: \"ಓ ಕೃಷ್ಣಾ, ನೀನು ಒಮ್ಮೆ ಹೋರಾಡು ಎನ್ನು ತ್ತಿ ಇನ್ನೊ ಮ್ಮೆ ಕರ್ಮಸಂನ್ಯಾಸ ಮಾಡು\nಅನ್ನು ತ್ತಿ. ಒಂದು ವೇಳೆ ಕರ್ಮಸಂನ್ಯಾಸ ಅಂದರೆ ಕರ್ಮತ್ಯಾಗವಾದರೆ ಇದು ಒಂದಕ್ಕೊಂದು ವಿರುದ್ಧ. ಇದರಲ್ಲಿ\nಯಾವುದು ಶ್ರೇಯಸ್ಕರ ಎನ್ನು ವುದನ್ನು ನಿಶ್ಚಿತವಾಗಿ ಹೇಳು\" ಎಂದು. ಯುದ್ಧ ಮಾಡುವಾಗ ದ್ವಂದ್ವ ಅನ್ನುವುದು\n\nಇದ್ದೇ ಇದೆ. ದ್ವಂದ್ವತ್ಯಾಗದಿಂದ ಯುದ್ಧ ಮಾಡುವುದು ಹೇಗೆ?",
  "5.2": "ಭಗವಾನುವಾಚ- ಭಗವಂತ ಹೇಳಿದನು\n\nಸಂನ್ಯಾಸಃ ಕರ್ಮಯೋಗಃ ಚ ನಿಃಶ್ರೇಯಸ ಕರೌ ಉಭೌ |\n\nತಯೋಃ ತು ಕರ್ಮ ಸಂನ್ಯಾಸಾತ್‌ ಕರ್ಮಯೋಗಃ ವಿಶಿಷ್ಯತೇ -- ಕರ್ಮಸಂನ್ಯಾಸ ಮತ್ತು ಕರ್ಮಯೋಗ\nಎರಡೂ ಒಳಿತಿನ ದಾರಿಗಳೇ. ಅವುಗಳಲ್ಲಿ ಕರ್ಮಸಂನ್ಯಾಸಕ್ಕಿಂತ ಕರ್ಮಯೋಗ ಮಿಗಿಲು.",
  "5.3": "ಜ್ಞೇಯಃ ಸ ನಿತ್ಯಸಂನ್ಯಾಸೀ ಯಃ ನದ್ವೇಷ್ಟಿನ ಕಾಂಕ್ಟತಿ ।\nನಿರ್ದ್ವಂದ್ವಃ ಹಿ ಮಹಾಬಾಹೋ ಸುಖಮ್‌ ಬಂಧಾತ್‌ ಪ್ರಮುಚ್ಯತೇ -- ದ್ವೇಷಿಸದವನು, ಮತ್ತು ಬಯಸದವನು\nನಿಜವಾದ ಸಂನ್ಯಾಸಿಯೆಂದರಿಯಬೇಕು. ಮಹಾವೀರಾ, ಇಂತಹ ದ್ವಂದ್ವಗಳನ್ನು ಗೆದ್ದವನು ಹಾಯಾಗಿ ಕರ್ಮ\n\nಸೆರೆಯಿಂದ ಪಾರಾಗುತ್ತಾನೆ.\n\nಇಲ್ಲಿ ಅರ್ಜುನನ ಪ್ರಶ್ನೆಗೆ ಕೃಷ್ಣನ ಉತ್ತರ ಒಗಟಿನ ರೂಪದಲ್ಲಿದೆ. ಈ ಶ್ಲೋಕವನ್ನು ಎಚ್ಚರಿಕೆಯಿಂದ ಬಿಡಿಸಿ\n\nಅರ್ಥೈಸಿಕೊಳ್ಳಬೇಕು. ಇಲ್ಲಿ ಹೇಳುವ ಸಂನ್ಯಾಸ ಸಂನ್ಯಾಸಾಶ್ರಮವಲ್ಲ. ಯಾರು ರಾಗ ದ್ವೇಷವನ್ನು ದಾಟಿ\nನಿಲ್ಲುತ್ತಾನೋ ಅವನು ಸಂನ್ಯಾಸಿ. ಸ-ಅಹಂ-ನ್ಯಾಸ-ಸಂನ್ಯಾಸ. 'ಸ'. ಅಂದರೆ. ಸಂಪೂರ್ಣವಾದ,\n\nಸಮೀಚೀನವಾದ, ದೋಷರಹಿತ ಮತ್ತು ಗುಣಪೂರ್ಣನಾದ ಭಗವಂತ. ಅವನಲ್ಲಿ ನಮ್ಮ ಅಹಂ(ರಾಗ ದ್ವೇಷ-\nಅಹಂಕಾರ)ನ್ನು ನ್ಯಾಸ ಮಾಡುವುದು ಸಂನ್ಯಾಸ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: \"ಠರ್ಮಯೋಗ ಕರ್ಮಸಂನ್ಯಾಸಕ್ಕಿಂತ\nಮಿಗಿಲು” ಎಂದು. ಏಕೆಂದರೆ ಇಲ್ಲಿ ಅರ್ಜುನ 'ನನಗೆ ಕೌರವರ ಮೇಲೆ ದ್ವೇಷವಿಲ್ಲ, ನಾವೇ ಗೆಲ್ಲಬೇಕು ಎನ್ನುವ\n\nಬಯಕೆ ಇಲ್ಲ, ನನಗೆ ಯಾವ ಫಲದ ಆಸೆಯೂ ಇಲ್ಲ' ಎಂದು ಯುದ್ಧ ಮಾಡದೇ ನಿರ್ಲಿಪ್ತನಾಗಿ-ನಿಷ್ಕ್ರೀಯನಾಗಿ\nಕುಳಿತರೆ ಅದು ಕರ್ಮಸಂನ್ಯಾಸವಾಗುತ್ತದೆ. ಆದರೆ ಹೀಗೆ ಸುಮ್ಮನೆ ಕುಳಿತರೆ ಕರ್ತವ್ಯಕರ್ಮ(ಕರ್ಮಯೋಗ)\nಮಾಡಿದಂತಾಗುವುದಿಲ್ಲ . ಇದರಿಂದಾಗಿ ಅಧರ್ಮಕ್ಕೆ ಜಯವಾಗುತ್ತದೆ. ಆದ್ದರಿಂದ ಕರ್ಮಸಂನ್ಯಾಸ ಮತ್ತು\nಕರ್ಮಯೋಗ ಜೊತೆ-ಜೊತೆಯಾಗಿರಬೇಕು. ಕರ್ಮಯೋಗವಿಲ್ಲದ ಕರ್ಮಸಂನ್ಯಾಸ ಎಂದೂ ಶ್ರೇಯಸ್ಸನ್ನು\nತರುವುದಿಲ್ಲ ಎನ್ನುವುದು ಕೃಷ್ಣನ ಉತ್ತರ.\nಸಂನ್ಯಾಸ ಅನ್ನು ವುದು ಅರ್ಥಪೂರ್ಣವಾಗಬೇಕಾದರೆ ಕಾಮ ಕ್ರೋಧಗಳ ತ್ಯಾಗದ ಜೊತೆಗೆ ಕ್ರಿಯೆ ಇರಬೇಕು.\nಹೋರಾಡಬೇಕು-ಆದರೆ ರಾಗದ್ವೇಷದಿಂದಲ್ಲ. ಕ್ರಿಯೆ ಇಲ್ಲದೆ. ರಾಗ-ದ್ವೇಷ ತ್ಯಾಗಕ್ಕೆ ಅರ್ಥವಿಲ್ಲ. ಆದ್ದರಿಂದ\nದ್ವಂದ್ವಾತೀತವಾಗಿ ಕರ್ಮ ಮಾಡಬೇಕು ಎನ್ನುವುದು ಕೃಷ್ಣನ ಸಂದೇಶ.\nನಮ್ಮ ಜೀವನವೇ ಒಂದು ಹೋರಾಟ. ಇಲ್ಲಿ ನಮ್ಮ ಕರ್ತವ್ಯಕರ್ಮದಿಂದ ದೂರ ಸರಿದು, ರಾಗ-ದ್ವೇಷ, ಕಾಮ-\nಕ್ರೋಧವನ್ನು ಬಿಟ್ಟು, ನಿಷ್ಕ್ರೀಯನಾಗಿ, \"ಕರ್ಮಸಂನ್ಯಾಸವನ್ನು ಸಾಧಿಸಿದೆ' ಎಂದುಕೊಂಡರೆ ನಮ್ಮ ಜೀವನ\nವ್ಯರ್ಥ. ಅದರಿಂದ ಎಂದೂ ಶ್ರೇಯಸ್ಸಿ ಲ್ಲ ಮತ್ತು ಮೋಕ್ಷವಿಲ್ಲ. ರಾಗ-ದ್ವೇಷ ತ್ಯಾಗದ ಜೊತೆಗೇ, ಬದುಕು ಎನ್ನು ವ\nಜೀವನ ಸಂಗ್ರಾಮದಲ್ಲಿ. ನಮ್ಮ ಕರ್ತವ್ಯಕರ್ಮದ ಮುಖೇನ ಹೋರಾಟ ಮಾಡುವುದೇ ನಿಜವಾದ\nಜೀವನಧರ್ಮ. ಈ ರೀತಿ ದ್ವಂದ್ವಾತೀತ ಬದುಕನ್ನು ಬಾಳುವವನು ಕರ್ಮದ ಸೆರೆಯಿಂದ ಪಾರಾಗುತ್ತಾನೆ.\nಇಲ್ಲಿ ಕೃಷ್ಣ ಅರ್ಜುನನನ್ನು ಮಹಾಬಾಹು ಎಂದು ಸಂಬೋಧಿಸಿದ್ದಾನೆ. ಹಿಂದೆ ಹೇಳಿದಂತೆ ಮಹಾಬಾಹು\nಎಂದರೆ ಮಹಾವೀರ ಎನ್ನು ವುದು ಮೇಲ್ನೋಟದ ಅರ್ಥ. ಇಲ್ಲಿ ಈ ವಿಶೇಷಣಕ್ಕೆ ವಿಶೇಷ ಅರ್ಥವಿದೆ. 'ಮಹಾಬಾ'\nಅಂದರೆ ರಾಗ-ದ್ವೇಷ, ಮತ್ತು ಕಾಮನೆಗಳ ಮಡುವಿನಲ್ಲಿರುವವ. ಇಂತಹ ಮಹತ್ತರವಾದ ರಾಗ-ದ್ವೇಷಗಳನ್ನು\nತ್ಯಾಗ ಮಾಡಿದವ ಮಹಾಬಾಹು. \"ನಿನ್ನಲ್ಲಿ ಕರ್ಮಸಂನ್ಯಾಸವಿದೆ, ಅದರ ಜೊತೆಗೆ ಕರ್ಮಯೋಗ ಮಾಡಲು\nಅರ್ಹತೆಯುಳ್ಳ ಮಹಾವೀರ ನೀನು\" ಎನ್ನುವ ಧ್ವನಿ ಈ ಸಂಬೋಧನೆಯಲ್ಲಿದೆ. ನಮ್ಮ ಜೀವನ ಸಂಗ್ರಾಮದಲ್ಲಿ\nರಾಗ-ದ್ವೇಷಗಳನ್ನು ಬಿಟ್ಟು ಕರ್ಮ ಮಾಡಬೇಕು. ಕರ್ಮಸಂನ್ಯಾಸ ಮತ್ತು ಕರ್ಮಯೋಗ ಎರಡೂ ಒಟ್ಟಿಗಿರಬೇಕು\nಎನ್ನುವುದು ಮೂಲ ಸಂದೇಶ. ಅದಕ್ಕೆ ಹೊಂದಿಕೆಯಾಗುವಂತೆ ಇಲ್ಲಿ 'ಮಹಾಬಾಹು' ಎನ್ನುವ ವಿಶೇಷಣ\nಬಳಕೆಯಾಗಿದೆ.\n",
  "5.4": "ಸಾಂಖ್ಯ ಯೋಗೌ ಪೃಥಕ್‌ ಬಾಲಾಃ ಪ್ರವದಂತಿ ನ ಪಂಡಿತಾಃ ।\n\nಏಕಮ್‌ ಅಪಿ ಅಸ್ಥಿತಃ ಸಮ್ಯಕ್‌ ಉಭಯೋಃ ವಿಂದತೇ ಫಲಮ್‌ - ಜ್ಞಾನ ಮತ್ತು ಕರ್ಮದ ದಾರಿ ಬೇರೆಬೇರೆ\n[ಒಂದು ಸಂನ್ಯಾಸಿಗಳಿಗೆ ಹಾಗೂ ಇನ್ನೊಂದು ಸಂಸಾರಿಗಳಿಗೆ]1 ಎಂದು ನುಡಿದವರು ಬಾಲಿಷರು[ತಿಳಿಗೇಡಿಗಳು];\nತಿಳಿದವರಲ್ಲ. ಯಾವುದೇ ಒಂದು ದಾರಿಯಲ್ಲಿ ಸರಿಯಾಗಿ ನಡೆದವನು ಎರಡರ ಫಲವನ್ನೂ ಪಡೆಯುತ್ತಾನೆ.\n\nಹಿಂದೆ ಕರ್ಮಸಂನ್ಯಾಸ ಮತ್ತು ಕರ್ಮಯೋಗವನ್ನು ವಿವರಿಸಿದಂತೆ ಕೃಷ್ಣ ಇಲ್ಲಿ ಸಾಂಖ್ಯವನ್ನು(ಜ್ಞಾನ-Spiritual Wisdom) ಮತ್ತು ಯೋಗವನ್ನು(ಅನುಷ್ಠಾನ-Spiritual Practice) ವಿವರಿಸುತ್ತಾನೆ. ಶಾಸ್ತ್ರದಲ್ಲಿ ಸಾಂಖ್ಯ(ಸಮ್ಯಕ್‌\n\nಖ್ಯಾತಿ) ಎಂದರೆ ಗಣಿತವಲ್ಲ; ಅದು ಶುದ್ಧ ಆತ್ಮತತ್ವವಿಜ್ಞಾನ-ಭಗವಂತನ ಜ್ಞಾನ. ಯಾರ ಅಂಕೆಯಲ್ಲಿ ಈ ಇಡೀ\nಜಗತ್ತು ನಡೆಯುತ್ತಿದೆಯೋ ಅವನ ಅರಿವು. ಇದನ್ನು ತಿಳಿಯದೇ ಇರುವವರನ್ನು ಕೃಷ್ಣ ಬಾಲಿಷರು ಹಾಗೂ\nಅಂತವರ ಮಾತಿಗೆ ಮೂಲ ಆಧಾರ ಎನ್ನು ವುದಿಲ್ಲ ಎನ್ನುತ್ತಾನೆ. ಇಷ್ಟು ಹೇಳಿ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ\n\"ಏಕಮಪ್ಯಾಸ್ಥಿತಃ ಸಮ್ಯಗುಭಯೋರ್ವಿಂದತೇ ಫಲಮ್‌\" ಎಂದು. ಅಂದರೆ “ಯಾವುದೇ ಒಂದನ್ನು ನೀನು\nಚೆನ್ನಾಗಿ ಆಚರಣೆಗೆ ತಂದರೂ, ಎರಡರ ಫಲವನ್ನೂ ಪಡೆಯುತ್ತಿ' ಎಂದರ್ಥ. ಇಲ್ಲಿ ಪುನಃ ನಮಗೆ\nಗೊಂದಲವಾಗಬಹುದು. ಇದರರ್ಥ ಜ್ಞಾನವನ್ನು ಮಾತ್ರ ಅಥವಾ ಕರ್ಮವನ್ನು ಮಾತ್ರ ಆಚರಣೆ ಮಾಡುವುದು\nಎಂದಲ್ಲ. ನಾವು ಕರ್ಮವನ್ನು ಚೆನ್ನಾಗಿ ಮಾಡುವದು ಎಂದರೆ ತಿಳಿದು ಜ್ಞಾನಪೂರ್ವಕವಾಗಿ ಮಾಡುವದು. ಅದೇ\nರೀತಿ ಜ್ಞಾನ ಚೆನ್ನಾಗಿರುವುದು ಎಂದರೆ ತಿಳಿದದ್ದನ್ನು ಅನುಷ್ಠಾನಗೊಳಿಸುವುದು. ಆದ್ದರಿಂದ ಒಂದು\n'ಜ್ಯಾನಪ್ರಧಾನ' ಇನ್ನೊಂದು 'ಕರ್ಮಪ್ರಧಾನ'ವಾಗಿರಬಹುದು. ಆದರೆ ಒಂದು ಇನ್ನೊಂದಕ್ಕೆ ಪೂರಕ. ಯಾರು\nಇದನ್ನು ತಿಳಿದಿದ್ದಾರೋ ಅವರು ಪಂಡಿತರು ಹಾಗೂ ಅವರು ನಿಜವಾದ ಫಲವನ್ನು ಪಡೆಯುತ್ತಾರೆ.\n",
  "5.5": "ಯತ್‌ ಸಂಖ್ಯೇೈಃ ಪ್ರಾಪ್ಯತೇ ಸ್ಥಾನಮ್‌ ತತ್‌ ಯೋಗ್ಯೆಃ ಅಪಿ ಗಮ್ಯತೇ ।\n\nಏಕಮ್‌ ಸಾಂಖ್ಯಮ್‌ ಚ ಯೋಗಮ್‌ ಚ ಯಃ ಪಶ್ಯತಿ ಸಃ ಪಶ್ಯತಿ -- ಜ್ಞಾನಯೋಗಿಗಳು ಪಡೆಯುವ ತಾಣದೆಡೆ\nಕರ್ಮಯೋಗಿಗಳೂ ನಡೆಯುತ್ತಾರೆ. ಜ್ಞಾನ ಮತ್ತು ಕರ್ಮದ ದಾರಿಗಳ ಗುರಿ ಒಂದೇ ಎಂದು ತಿಳಿದವನೇ\nನಿಜವಾಗಿ ತಿಳಿದವನು.\n\nಜ್ಞಾನಿಗಳು. ತಮಗೋಸ್ಕರವಲ್ಲದೆ ಲೋಕಕ್ಕೆ ಮಾರ್ಗದರ್ಶನ ಮಾಡುವ ಸಲುವಾಗಿಯೂ ಕರ್ಮ\nಮಾಡಬೇಕಾಗುತ್ತದೆ. ಏಕೆಂದರೆ ಸಮಾಜ ಅವರನ್ನು ಅನುಸರಿಸುತ್ತದೆ. ಇದು ಅವರ ಮೇಲಿರುವ ಸಾಮಾಜಿಕ\nಜವಾಬ್ದಾರಿ. ಆದ್ದರಿಂದ ಜ್ಞಾನ ಮತ್ತು ಕರ್ಮ ಒಂದಕ್ಕೊಂದು ಪೂರಕ. ಜ್ಞಾನಪ್ರದ ಮತ್ತು ಕರ್ಮಪ್ರದ ಈ\nಮಾರ್ಗದ ಗುರಿ ಒಂದೇ. ಜ್ಞಾನಪ್ರಧಾನವಾಗಿ ಕರ್ಮ ಮಾಡುವ ಖುಷಿಗಳು, ದೇವತೆಗಳು, ಮತ್ತು\nಕರ್ಮಪ್ರಧಾನವಾಗಿ ಜ್ಞಾನದಿಂದ ಕರ್ಮಮಾಡುವವರು ಸೇರುವ ಗುರಿ ಒಂದೇ-ಅದು ಆ ಭಗವಂತನನ್ನು. ಇಲ್ಲಿ\nಕರ್ಮಸಂನ್ಯಾಸವೇ ಬೇರೆ ಮತ್ತು ಕರ್ಮಯೋಗವೇ ಬೇರೆ ಎನ್ನುವುದು ಅರ್ಥಶೂನ್ಯ. ಇವೆರಡೂ ಒಂದಕ್ಕೊಂದು\nಪೂರಕ. ಯಾರು ಈ ಸತ್ಯವನ್ನು ತಿಳಿದಿದ್ದಾರೋ ಅವರು'ತಿಳಿದವರು'\n",
  "5.6": "ಸಂನ್ಯಾಸಃ ತು ಮಹಾಬಾಹೋ ದುಃಖಮ್‌ ಆಪ್ತುಮ್‌ ಅಯೋಗತಃ |\n\nಯೋಗ ಯುಕ್ತಃ ಮುನಿಃ ಬ್ರಹ್ಮ ನ ಚಿರೇಣ ಅಧಿಗಚ್ಛತಿ-ಓ ಮಹಾವೀರಾ, ಕರ್ಮಯೋಗವಿರದ ಬರಿಯ ಸಂನ್ಯಾಸ\n[ದ್ವಂದ್ವ ತ್ಯಾಗ] ಬನ್ನವನ್ನೇ ತಂದೀತು.(ಭಗವಂತನ ಪೂಜೆಯೆಂದು ಕರ್ಮ ಮಾಡುವ ಬದಲು ಕರ್ಮವನ್ನೇ\nತೊರೆಯುವುದು ನರಕದ ದಾರಿ]. ಕರ್ಮ ಮಾಡುತ್ತಾ ದ್ವಂದ್ವವನ್ನು ಗೆದ್ದವನು ಭಗವಂತನನ್ನು ಪಡೆಯಲು\n\nತಡವಾಗದು.\n\nಕರ್ಮಯೋಗವಿಲ್ಲದ ಬರಿಯ ದ್ವಂದ್ವತ್ಯಾಗ [ಸಂನ್ಯಾಸ] ವ್ಯರ್ಥ. ಶಾಸ್ತ್ರವನ್ನು ಓದಿ ನನಗೆ ಜ್ಞಾನ ಬಂತು,\nನಾನು ದ್ವಂದ್ವಾತೀತ, ನನಗೆ ಯಾವ ಕರ್ಮವೂ ಬೇಕಾಗಿಲ್ಲ ಎಂದು ತಿಳಿದು ನಿಷ್ಕ್ರೀಯನಾದರೆ ಅದು ನಮ್ಮನ್ನು\nಅಧೋಗತಿಗೆ ತಳ್ಳುತ್ತದೆ. ಆದರೆ ದ್ವಂದ್ವಾತೀತನಾಗಿ ಕಾಮಕ್ರೋಧವನ್ನು ಗೆದ್ದು ಜ್ಞಾನಪೂರ್ವಕವಾಗಿ ಕರ್ಮ\nಮಾಡಿದರೆ ಅದರಿಂದ ಮೋಕ್ಷ ನಿಶ್ಚಿತ.",
  "5.7": "ಯೋಗಯುಕ್ತಃ ವಿಶುದ್ಧ ಆತ್ಮಾ ವಿಜಿತ ಆತ್ಮಾ ಜಿತ ಇಂದ್ರಿಯಃ ।\n\nಸರ್ವ ಭೂತ ಆತ್ಮಭೂತ ಆತ್ಮಾ ಕುರ್ವನ್‌ ಅಪಿ ನ ಲಿಷ್ಯತೇ-- ಕರ್ಮಯೋಗದಲ್ಲಿ ತೊಡಗಿದವನು, ತಿಳಿಯಾದ\nಬಗೆಯವನು, ಬಗೆಯ ಗೆದ್ದವನು. ಇಂದ್ರಿಯಗಳನ್ನೂ ಗೆದ್ದವನು. ಎಲ್ಲಾ ಜೀವಿಗಳನ್ನು ಪೊರೆವ ಭಗವಂತ ತನ್ನ\nದೊರೆಯೆಂದು ತಿಳಿದವನು.[ಭಗವಂತನಲ್ಲೇ ಬಗೆ ನೆಟ್ಟವನು]. ಮಾಡಿದರೂ ಅಂಟಿಸಿಕೊಳ್ಳುವುದಿಲ್ಲ.\n\nಕರ್ಮಯೋಗದಲ್ಲಿ ತೊಡಗಿದವನು ತನ್ನ ಮನೋನಿಗ್ರಹ ಮಾಡಿ ಶುದ್ಧವಾದ ಮನಸ್ಸಿನಿಂದ ಶುದ್ಧಕರ್ಮವನ್ನು\nಮಾಡಬೇಕು. ಮನಸ್ಸನ್ನು ಗೆಲ್ಲಬೇಕಾದರೆ ಭಗವಂತನ ಒಲವು ಬೇಕು. ಮನಸ್ಸನ್ನು ಗೆದ್ದವನು ಇಂದ್ರಿಯಗಳನ್ನು\nಗೆಲ್ಲುತ್ತಾನೆ-ಅದರಿಂದ ಆತ್ಮ ಶುದ್ಧಿಯಾಗುತ್ತದೆ. ಆಗ ಸರ್ವಭೂತಗಳಿಗೂ ಆತ್ಮಭೂತನಾದ ಭಗವಂತನೇ ನನ್ನ\nಆತ್ಮ ಎನ್ನುವ ಅರಿವಾಗುತ್ತದೆ. ಸರ್ವಗತ, ಸರ್ವನಿಯಾಮಕ ಭಗವಂತ ನನ್ನೊಳಗೂ ಇದ್ದಾನೆ, ಅವನೇ\nವಿಶ್ವನಿಯಾಮಕನಾಗಿ ವಿಶ್ವದಲ್ಲಿ ತುಂಬಿದ್ದಾನೆ. ಜಗತ್ತನ್ನು ನಿಯಂತ್ರಿಸುವ ಅನಂತಶಕ್ತಿ ಅಣೋರಣೀಯವಾಗಿ\nನನ್ನ ಜೀವಸ್ವರೂಪದೊಳಗೂ ತುಂಬಿದೆ ಎನ್ನುವ ಅನುಷ್ಠಾನದಿಂದ, ಸರ್ವಭೂತಗಳಲ್ಲಿ ಅಂತರ್ಯಾಮಿಯಾದ\nಭಗವಂತನಲ್ಲಿ ಮನಸ್ಸನ್ನು ನೆಲೆಗೊಳಿಸಿ ಕರ್ಮ ಮಾಡಿದಾಗ, ನಮಗೆ ಕರ್ಮ ಅಂಟಿಕೊಳ್ಳುವುದಿಲ್ಲ.\n\nಕರ್ಮಸಂನ್ಯಾಸ ಮತ್ತು ಕರ್ಮಯೋಗ ಎರಡನ್ನು ಬೆರೆಸಿ ಜೀವನದಲ್ಲಿ ಕರ್ಮಾನುಷ್ಠಾನ ಮಾಡಬೇಕು ಎಂದು\nವಿವರಿಸಿದ ಕೃಷ್ಣ, ನಮ್ಮ ದೈನಂದಿನ ಜೀವನದಲ್ಲಿ ಈ ರೀತಿಯ ಕರ್ಮಾನುಷ್ಠಾನ ಅಂದರೆ ಏನು ಎನ್ನುವುದರ\n\nವಿವರಣೆಯನ್ನು ಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ಕೊಡುತ್ತಾನೆ.\n\nನೈವ ಕಿಂಚಿತ್‌ ಕರೋಮೀತಿ ಯುಕ್ತೋ",
  "5.8": "ಪ್ರಲಪನ್‌ ವಿಸೃಜನ್‌ ಗೃಹ್ಣನ್ನುನ್ಮಿಷನ್‌ ನಿಮಿಷನ್ನಪಿ |\nಇಂದ್ರಿಯಾಣೀಂದ್ರಿಯಾರ್ಥೇಷು ವರ್ತಂತ ಇತಿ ಧಾರಯನ್‌",
  "5.9": "ನ ಏವ ಕಿಂಚಿತ್‌ ಕರೋಮಿ ಇತಿ ಯುಕ್ತಃ ಮನ್ಯೇತ ತತ್ತ್ವವಿತ್‌।\n\nಪಶ್ಯನ್‌ ಶೃಣ್ವನ್‌ ಸ್ಪೃಶನ್‌ ಜಿಫ್ರನ್‌ ಅಶ್ಡನ್‌ ಗಚ್ಛನ್‌ ಸ್ವಪನ್‌ ಶ್ವಸನ್‌ ॥\n\nಪ್ರಲಪನ್‌ ವಿಸೃಜನ್‌ ಗೃಹ್ಣನ್‌ ಉನ್ಮಿಷನ್‌ ನಿಮಿಷನ್‌ ಅಪಿ ।\n\nಇಂದ್ರಿಯಾಣಿ ಇಂದ್ರಿಯ ಅರ್ಥೇಷು ವರ್ತಂತೇ ಇತಿ ಧಾರಯನ್‌ - ನಿಜವರಿತ ಸಾಧಕ ತಾನಾಗಿ ಏನೂ\nಮಾಡುತ್ತಿಲ್ಲ ಎಂದು ತಿಳಿಯಬೇಕು- ಕಾಣುವಾಗ, ಕೇಳುವಾಗ, ಮುಟ್ಟು ವಾಗ, ಮೂಸುವಾಗ, ತಿನ್ನು ವಾಗ,\nತಿರುಗುವಾಗ, ಮಲಗುವಾಗ, ಉಸಿರುವಾಗ, ಉಸುರುವಾಗ, ಕಳೆಯುವಾಗ, ಕೊಳ್ಳುವಾಗ, ಎವೆ ಮುಚ್ಚುವಾಗ,\nಎವೆ ಬಿಚ್ಚುವಾಗ ಕೂಡಾ-ಇಂದ್ರಿಯಗಳು ತಮ್ಮ ಕೆಲಸದಲ್ಲಿ ತೊಡಗಿವೆ ಎಂದು ಭಾವಿಸುತ್ತಾ.\n\nನಮ್ಮ ಜೀವನದಲ್ಲಿ ದೇವರಪೂಜೆ ಮಾತ್ರ ಅನುಷ್ಠಾನವಲ್ಲ. ನಮ್ಮ ಪ್ರತಿಯೊಂದು ನಡೆಯೂ ಒಂದು\nಕರ್ಮಯೋಗವಾಗಬೇಕು. ಯಾವುದೋ ಕಾಲ ವಿಶೇಷದಲ್ಲಿ ಮಾತ್ರ ದೇವರ ಪೂಜೆ ಮಾಡುವುದಲ್ಲ. ನಮ್ಮ\nಇಡೀ ಬದುಕೇ ಒಂದು ಯಜ್ಞವಾಗಬೇಕು. ಯಜ್ಞವನ್ನು ಕನ್ನಡದಲ್ಲಿ 'ಬೇಳುವೆ' ಎನ್ನುತ್ತಾರೆ. ನಮ್ಮ ಬಾಳುವೆಯೇ\nಒಂದು ಬೇಳುವೆಯಾಗಬೇಕು.\n\nಕರ್ಮಾನುಷ್ಠಾನ ಮಾಡುವವನು \"ನಾನು ನಾನಾಗಿ ಏನನ್ನೂ ಮಾಡುತ್ತಿಲ್ಲ, ನನ್ನದು ಇಚ್ಛಾಪೂರ್ವಕ ಕೃತಿ ಆದರೆ\nಇಲ್ಲಿ ನನಗೆ ಸ್ವಾತಂತ್ರವಿಲ್ಲ” ಎನ್ನುವ ಸತ್ಯವನ್ನು ಅರಿತಿರಬೇಕು. ನಾವು ಮಾಡಬೇಕು ಎಂದುಕೊಂಡದ್ದನ್ನು\nನಮ್ಮಿಂದ ಮಾಡಲು ಆಗುವುದಿಲ್ಲ, ನಾವು ಬಯಸಿದ್ದು ಸಿಗುವುದಿಲ್ಲ, ಫಲದಲ್ಲಿ ನಮಗೆ ಸ್ವಾತಂತ್ರ್ಯವಿಲ್ಲ. ಇದು\nಪ್ರತಿಯೊಬ್ಬರ ಅನುಭವಕ್ಕೆ ಬರುವ ವಿಚಾರ. ಆದರೆ ಕ್ರಿಯೆ ಮಾತ್ರ ನಮ್ಮ ಮುಖೇನ ಆಗುತ್ತಿರುತ್ತದೆ.\n\n'ನಾನು ಇಂತಹದ್ದೇ ಸಿಗಬೇಕು, ಇಂತಾದ್ದು ಸಿಗಬಾರದು ಎನ್ನುವ ಇಚ್ಛೆಯಿಂದಾಗಲೀ, ನಾನು ಮಾಡುತ್ತಿದ್ದೇನೆ\nಎನ್ನುವ ಅಹಂಕಾರದಿಂದಾಗಲೀ ಮಾಡುತ್ತಿಲ್ಲ; ನನ್ನೊಳಗಿರುವ ಭಗವಂತ ಇದನ್ನು ಮಾಡಿಸುತ್ತಿದ್ದಾನೆ' ಎಂದು\nತತ್ವಜ್ಞಾನಿ. ತಿಳಿದಿರುತ್ತಾನೆ. . ಆದ್ದರಿಂದ ಯಾವುದರಲ್ಲೂ \"ನಾನು, ನನ್ನದು\" ಎನ್ನುವ ಅಹಂಕಾರ\nಅವನಿಗಿರುವುದಿಲ್ಲ. ಎಲ್ಲವೂ ಭಗವಂತನ ಇಚ್ಛೆಯಂತೆ ನೆಡೆಯುತ್ತದೆ ಹೊರತು ಇಲ್ಲಿ ನಾವು ಸ್ವತಂತ್ರ\nಕರ್ತಾರರಲ್ಲ ಎನ್ನುವ ನಿಜವನ್ನರಿತು ಆತ ತನ್ನ ಕ್ರಿಯೆಯನ್ನು ಮಾಡುತ್ತಾನೆ.\n\nಪಶ್ಯನ್‌-ನೋಡುವಾಗ, ಶೃಣ್ವನ್‌-ಕೇಳುವಾಗ, ಸ್ಪೃಶನ್‌-ಸ್ಪರ್ಶದಲ್ಲಿ, ಜಿಫ್ರನ್‌-ಮೂಸುವಾಗ, ಅಶ್ನನ್‌-\nತಿನ್ನುವಾಗ, ಗಚ್ಛನ್‌-ತಿರುಗುವಾಗ, ಸ್ವಪನ್‌-ಮಲಗುವಾಗ, ಶ್ವಸನ್‌-ಉಸಿರಿನಲ್ಲಿ, ಪ್ರಲಪನ್‌-ಮಾತಿನಲ್ಲಿ,\nವಿಸೃಜನ್‌-ವಿಸರ್ಜಿಸುವಾಗ, ಗೃಹ್ಣನ್‌-ಸ್ವೀಕರಿಸುವಾಗ, ಉನ್ಮಿಷನ್‌-ತೆರೆಯುತ್ತಾ, ನಿಮಿಷನ್‌-ಮುಚ್ಚುತ್ತಾ, ಹೀಗೆ\nತನ್ನೆಲ್ಲಾ ಕ್ರಿಯೆಯಲ್ಲಿ ತಾನೇನೂ ಮಾಡುತ್ತಿಲ್ಲ ಅನ್ನುವ ಅರಿವನ್ನು ತತ್ವಜ್ಞಾನಿ ತಿಳಿದಿರುತ್ತಾನೆ. ಉದಾಹರಣೆಗೆ-\nನಾವು ಒಂದು ಹೂವಿನ ಅಂದವನ್ನು ಕಣ್ಣಿನಿಂದ ಸವಿಯುತ್ತೇವೆ; ಅದರ ಪರಿಮಳವನ್ನು ಮೂಗಿನಿಂದ ಮೂಸಿ\n\nಆಸ್ವಾಧಿಸುತ್ತೇವೆ; ಆ ಹೂವನ್ನು ಮುಟ್ಟಿ-ಮುಡಿದು ಸಂತೋಷ ಪಡುತ್ತೇವೆ. ಈ ಹೂವನ್ನು ಸೃಷ್ಟಿಸಿದವ, ಅದಕ್ಕೆ\nಅಂದವನ್ನು ಕೊಟ್ಟವ ಆ ಭಗವಂತ. ಆ ಹೂವನ್ನು ನೋಡುವ ಕಣ್ಣನ್ನು ನಮಗೆ ಕೊಟ್ಟವ ಆತ(ಹುಟ್ಟು ಕುರುಡನಿಗೆ\nಈ ಯೋಗವಿಲ್ಲ). ಈ ಅನುಸಂಧಾನವಿದ್ದರೆ ನೋಡುವ-ಮುಟ್ಟುವ-ಮೂಸವ ಕ್ರಿಯೆಯಲ್ಲಿ 'ನನ್ನದು' ಎನ್ನುವ\nಅಹಂಕಾರಕ್ಕೆ ಎಡೆಯಿಲ್ಲ. ಅದೇ ರೀತಿ-ತಿನ್ನುವುದು: ಈ ಪ್ರಪಂಚದಲ್ಲಿ ಎಷ್ಟೋ ಜನ ಒಂದು ಹೊತ್ತಿನ ಆಹಾರಕ್ಕೂ\nಗತಿ ಇಲ್ಲದೇ ಇನ್ನೊಬ್ಬರ ಮುಂದೆ ಕೈಚಾಚಿಕೊಂಡು ಬದುಕುತ್ತಾರೆ. ಆದರೆ ನಮಗೆ ಭಗವಂತ ಮೂರು ಹೊತ್ತಿನ\nತುತ್ತಿಗೆ ಅನುಕೂಲ ಮಾಡಿ ಕೊಟ್ಟಿದ್ದಾನೆ ಅನ್ನುವ ಅನುಸಂಧಾನದಿಂದ ಊಟ ಮಾಡಿದಾಗ ಅದೊಂದು\nಯಜ್ಞವಾಗುತ್ತದೆ. ಇನ್ನು-ನಿದ್ದೆ: ನಿದ್ದೆಯಲ್ಲಿ ನಾವು ಭಗವಂತನ ಸಮೀಪದಲ್ಲಿರುತ್ತೇವೆ. ಆದರೆ ಆ ಎಚ್ಚರ\nನಮಗಿರುವುದಿಲ್ಲ. ಒಂದು ವೇಳೆ ನಿದ್ದೆಯೇ ಬಾರದಿದ್ದರೆ? ಇಡೀ ರಾತ್ರಿ ಕನಸಿನಲ್ಲೇ ಕಳೆದರೆ? ಇದನ್ನು ನಮ್ಮಿಂದ\nಉಹಿಸುವುದೂ ಕಷ್ಟ. ಹುಟ್ಟಿದಾಗ ನಮಗರಿವಿಲ್ಲದಂತೆ. ಉಸಿರಾಟ ಆರಂಭವಾಯಿತು. ನಿದ್ದೆಯಲ್ಲೂ\nನಮಗರಿವಿಲ್ಲದಂತೆ ನಮ್ಮ ಉಸಿರಿನ ಕ್ರಿಯೆ ನಿರಂತರ. ಆದರೆ ಈ ಉಸಿರು ಯಾವಾಗ ನಿಲ್ಲುತ್ತದೆ ಎನ್ನುವುದು\nನಮಗೆ ತಿಳಿದಿಲ್ಲ. ಹೀಗೆ ಪ್ರತಿಯೊಂದು ಕ್ರಿಯೆಯಲ್ಲಿ ಆ ವಿಶ್ವಶಕ್ತಿಯ ಅನುಸಂಧಾನವೇ ನಿಜವಾದ ಕರ್ಮಯೋಗ.\nಭಗವಂತ ನಮಗೆ ಅಮೂಲ್ಯವಾದ ಕೈ ಕೊಟ್ಟಿ ದ್ದಾನೆ. ಪ್ರಾಣಿಗಳಿಗೆ ನಾಲ್ಕೂ ಕಾಲೇ. ಕೈ ಇಲ್ಲ. ತನ್ನ ಮೈ ಮೇಲೆ\nಯಾವುದೋ ಜೀವಿ ಕುಳಿತು ರಕ್ತ ಹೀರುತ್ತಿದ್ದರೂ ಅದನ್ನು ಓಡಿಸುವ ಕೈ ಅವುಗಳಿಗಿಲ್ಲ. ಇಂತಹ ಅಮೂಲ್ಯವಾದ\nಕೈಯನ್ನು ಭಗವಂತ ನಮಗೆ ಕರುಣಿಸಿದ್ದಾನೆ. ಅತ್ಯಂತ ಸೂಕ್ಷ್ಮ ಇಂದ್ರಿಯವಾದ ಕಣ್ಣನ್ನು ರಕ್ಷಿಸುವ ರೆಪ್ಪೆಗಳು,\nಅವು ನಿರಂತರ ತೆರೆಯವುದು-ಬಿಚ್ಚುವುದರಿಂದ ಕಣ್ಣಿನ ರಕ್ಷಣೆ. ಒಂದು ವೇಳೆ, ಕಣ್ಣಿಗೆ ಏನಾದರೂ ಕಸ ಬಿದ್ದರೆ\nನಮಗರಿವಿಲ್ಲದಂತೆ ಕಣ್ಣಿಗೆ ನೀರಿನ ಸರಬರಾಜಾಗಿ ಕಣ್ಣಿನ ರಕ್ಷಣೆಯಾಗುತ್ತದೆ. ಈ ಅಪೂರ್ವ ಯಂತ್ರದ ವಿನ್ಯಾಸ\nಮಾಡಿದ ಶಿಲ್ಪಿ ಆ ಭಗವಂತ.\n\nನಮ್ಮ ಪ್ರತಿಯೊಂದು ಇಂದ್ರಿಯಗಳನ್ನೂ ಇಂದ್ರಿಯಾಭಿಮಾನಿ ದೇವತೆಗಳು ನಿಯಂತ್ರಿಸುತ್ತಾರೆ ಎನ್ನುವ\nವಿಚಾರವನ್ನು ನಾವು ಈ ಹಿಂದೆ ವಿಶ್ಲೇಷಿಸಿದ್ದೇವೆ. ಉದಾಹರಣೆಗೆ ಸೂರ್ಯ ಕಣ್ಣಿನ ಹಾಗೂ ಚಂದ್ರ ಕಿವಿಯ\nದೇವತೆ. ಸುಪರ್ಣಿ-ವಾರುಣಿ-ಪಾರ್ವತಿ ಶಬ್ದ-ಸ್ಪರ್ಶ-ಗಂಧದ ಅಭಿಮಾನಿ ದೇವತೆಯರು. ಮನೋಭಿಮಾನಿ\nದೇವತೆಯಾಗಿ ಗರುಡ ಶೇಷ ರುದ್ರರಿದ್ದಾರೆ. ಹೀಗೆ ನಮ್ಮ ಕ್ರಿಯೆಯ ಹಿಂದೆ ಅದ್ಭುತವಾದ ಆಧ್ಯಾತ್ಮಿಕ ಶಕ್ತಿ ಕೆಲಸ\nಮಾಡುತ್ತಿದೆ.\n",
  "5.10": "ಬ್ರಹ್ಮಣಿ ಆಧಾಯ ಕರ್ಮಾಣಿ ಸಂಗಮ್‌ ತ್ಯಕ್ತ್ವಾ ಕರೋತಿ ಯಃ ।\nಲಿಪ್ಯತೇ ನ ಸಃ ಪಾಪೇನ ಪದ್ಮಪತ್ರಮ್‌ ಇವ ಅಂಭಸಾ-ಕರ್ಮಗಳನ್ನು ಭಗವಂತನಲ್ಲಿ ಒಪ್ಪಿಸಿ, ನಂಟು ನೀಗಿ\nಮಾಡುವವನು ಪಾಪದಿಂದ ಅಂಟಿಸಿಕೊಳ್ಳುವುದಿಲ್ಲ-ತಾವರೆ ಎಲೆ ನೀರಿನಿಂದ ಹೇಗೋ ಹಾಗೆ.\n\nನಾವು ಪೂಜೆಯ ಕೊನೆಯಲ್ಲಿ \"ಶ್ರೀ ಕೃಷ್ಣಾರ್ಪಣ ಮಸ್ತು\" ಎಂದು ಹೇಳುತ್ತೇವೆ. ಇದರ ಅರ್ಥ \" ಆ ಭಗವಂತನಲ್ಲಿ\nಅರ್ಪಿತ\". ಅರ್ಪಿಸುವುದು ಎಂದರೆ \" ಈ ಕರ್ಮವನ್ನು ಭಗವಂತ ತನ್ನ ಪೂಜಾರೂಪವಾಗಿ ನನ್ನ ಮೂಲಕ ನನ್ನ\nಉದ್ಧಾರಕ್ಕಾಗಿ ಅವನೇ ಮಾಡಿಸಿಕೊಂಡ” ಎನ್ನುವ ಸಂಕಲ್ಪ. ಹೀಗೆ ನಾವು ಕರ್ಮವನ್ನು ಮಾಡಿದಾಗ ಯಾವ\nಕರ್ಮದ ಲೇಪವೂ ನಮಗೆ ಅಂಟುವುದಿಲ್ಲ. 'ನಾನು, ನನ್ನದು, ನನ್ನಿಂದ' ಎನ್ನುವ ಅಹಂಕಾರ\nಹೊರಟುಹೋಗುತ್ತದೆ. ಇದು ಆನಂದಮಯವಾದ ವಿಸ್ಮಯ. ತಾವರೆ ಎಲೆ ನೀರಿನಲ್ಲೇ ಇದ್ದರೂ ಕೂಡಾ ಹೇಗೆ\nನೀರನ್ನು ತನಗೆ ಅಂಟಿಸಿಕೊಳ್ಳುವುದಿಲ್ಲವೋ ಹಾಗೇ, ಕರ್ಮದ ಜೊತೆಗೇ ಇದ್ದು, ಕರ್ಮ ಮಾಡಿ, ಕರ್ಮವನ್ನು\nಅಂಟಿಸಿಕೊಳ್ಳದೇ ಇರುವುದು ಈ ಅನುಸಂಧಾನದಿಂದ ಮಾತ್ರ ಸಾಧ್ಯ.",
  "5.11": "ಕಾಯೇನ ಮನಸಾ ಬುದ್ಧ್ಯಾ ಕೇವಲೈಃ ಇಂದ್ರಿಯ್ಯೆಃ ಅಪಿ ।\nಯೋಗಿನಃ ಕರ್ಮ ಕುರ್ವಂತಿ ಸಂಗಮ್‌ ತ್ಯಕ್ತ್ವಾ ಆತ್ಮ ಶುದ್ಧಯೇ-ಯೋಗಿಗಳು ಮೈಯಿಂದ, ಮನದಿಂದ,\nಬುದ್ಧಿಯಿಂದ ಮತ್ತು ಬರಿಯ ಇಂದ್ರಿಯಗಳಿಂದ ಕರ್ಮ ಮಾಡುತ್ತಾರೆ. ನಂಟು ನೀಗಿ, ಬಗೆಯ ಶುದ್ಧಿಗಾಗಿ.\n\nಶಾಸ್ತ್ರದ ಸಂಪ್ರದಾಯದಂತೆ ಒಂದು ವಿಷಯವನ್ನು ಹೇಳಿ; ಕೊನೆಗೆ ಆ ರೀತಿ ಅನುಷ್ಠಾನ ಮಾಡಿದವರ ಬಗ್ಗೆ\nಹೇಳಿ; ನಮಗೆ ಆ ವಿಷಯದಲ್ಲಿ ಭರವಸೆ ಬರುವಂತೆ ಮಾಡುತ್ತಾರೆ. ಇದನ್ನು 'ಅರ್ಥವಾದ' ಎನ್ನುತ್ತಾರೆ.\nಯಾವುದೇ ವಿಷಯವನ್ನು ನಾವೇ ಮೊದಲು ಆರಂಭಿಸುವುದು ಅಂದರೆ ಸ್ವಲ್ಪ ಕಷ್ಟ. ಆದರೆ 'ಅದು ಹಿಂದಿನಿಂದಲೂ\nನಡೆದುಕೊಂಡು ಬಂದ ವಿಚಾರ' ಎಂದಾಗ ಆ ವಿಷಯದ ಬಗ್ಗೆ ನಮಗೆ ಧೈರ್ಯ ಹೆಚ್ಚು. ಹಾಗೇ ಕೃಷ್ಣ ಇಲ್ಲಿ\nಜ್ಞಾನಿಗಳು ಸಂಸ್ಯಾಸಯುಕ್ತವಾದ ಕರ್ಮಯೋಗ ಮಾಡುವುದನ್ನು ಪ್ರಸ್ತಾಪಿಸುತ್ತಾನೆ.\n\nಯೋಗಿಗಳು ದ್ವಂದ್ವಾತೀತವಾದ, ಫಲಕಾಮನೆ ಇಲ್ಲದೇ, 'ನನ್ನೊಳಗೆ ಭಗವಂತ ತನ್ನ ಪೂಜೆಯನ್ನು ನನ್ನ\nಮೂಲಕ ನನ್ನ ಉದ್ಧಾರಕ್ಕೋಸ್ಕರ ಮಾಡಿಸುತ್ತಿದ್ದಾನೆ' ಎಂದು ತಿಳಿದು ಕರ್ತವ್ಯ ದೃಷ್ಟಿಯಿಂದ ಕರ್ಮ\nಮಾಡುತ್ತಾರೆ. ಅವರಿಗೆ ಅಹಂಕಾರ-ಮಮಕಾರ ಇರುವುದಿಲ್ಲ; ಇದರಿಂದ ಮನಸ್ಸು ಶುದ್ಧವಾಗುತ್ತದೆ.\nಶುದ್ಧಮನಸ್ಸಿಗೆ ಶುದ್ಧ ವಿಷಯ ಗ್ರಹಣ ಮಾಡಲು ಸಾಧ್ಯ. ಶುದ್ಧ ವಿಷಯ ಗ್ರಹಣ ಎಂದರೆ ಶಾಸ್ತ್ರಕಾರರು ಯಾವ\nಅರ್ಥದಲ್ಲಿ ಹೇಳಿದ್ದಾರೋ ಅದೇ ಅರ್ಥದಲ್ಲಿ ಗ್ರಹಿಸುವುದು. ಹೀಗೆ ಅರ್ಥ ಮಾಡಿಕೊಳ್ಳಬೇಕಾದರೆ ನಮ್ಮ ಮನಸ್ಸು\nಶಾಸ್ತ್ರಕಾರರ ಮನಸ್ಸಿಗೆ ಶ್ರುತಿಗೂಡಬೇಕು ಅಥವಾ ನಾವು ಅವರ ಸ್ಥಾನಕ್ಕೇರಬೇಕು ಹಾಗೂ ಅವರ\nಸ್ಥಾನದಲ್ಲಿ ನಿಂತು ಯೋಚಿಸಬೇಕು. ಇಲ್ಲದಿದ್ದರೆ ನಿಜವಾದ ವಿಷಯ ಗ್ರಹಣವಾಗುವುದಿಲ್ಲ. ಇಲ್ಲಿ ಕೃಷ್ಣ\nಹೇಳುತ್ತಾನೆ: \"ಯೋಗಿಗಳೂ ಕೂಡಾ ಅಹಂಕಾರ-ಮಮಕಾರ ತೊರೆದು (ಸಂಗಂ ತ್ಯಕ್ತ್ವಾ) ಭಗವದರ್ಪಣ\nಬುದ್ಧಿಯಿಂದ- ಮೈಯಿಂದ, ಮನದಿಂದ, ಬುದ್ಧಿಯಿಂದ ಮತ್ತು ಇಂದ್ರಿಯಗಳಿಂದ ಕರ್ಮಾನುಷ್ಠಾನವನ್ನು\n\nಮಾಡುತ್ತಾರೆ\" ಎಂದು. ಈ ವಿಚಾರವನ್ನು ಮತ್ತಷ್ಟು ಒತ್ತುಕೊಟ್ಟು ಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ಕೃಷ್ಣ ವಿವರಿಸುತ್ತಾನೆ.",
  "5.12": "ಯುಕ್ತಃ ಕರ್ಮಫಲಮ್‌ ತ್ಯಕ್ತ್ವಾ ಶಾಂತಿಮ್‌ ಆಪ್ನೋತಿ ನೈಷ್ಠಿಕೀಮ್‌ |\n\nಅಯುಕ್ತಃ ಕಾಮ ಕಾರೇಣ ಫಲೇ ಸಕ್ತಃ ನಿಬದ್ಧ್ಯ ತೆ-ಯೋಗ ಬಲ್ಲವನು ಕರ್ಮಫಲದ ನಂಟು ತೊರೆದು ನಿಚ್ಚಳವಾದ\nನೆಮ್ಮದಿಯನ್ನು ಪಡೆಯುತ್ತಾನೆ... ಯೋಗಿಯಲ್ಲದವನು ಫಲದಲ್ಲಿ ಕಣ್ಣಿರಿಸಿ, ಆಸೆಪಡುತ್ತಾ ಅದರ\nಬಂಧಿಯಾಗುತ್ತಾನೆ.\n\nಕರ್ಮಯೋಗಕ್ಕೆ ತನ್ನನ್ನು ತೊಡಗಿಸಿಕೊಂಡವ, ಭಗವದ್‌ ಪ್ರಜ್ಞೆಯಲ್ಲಿ ಕರ್ಮ ಮಾಡತಕ್ಕವ-ಜ್ಞಾನಾನಂದದ\nತುದಿಯಾದ ಮೋಕ್ಷವನ್ನು ಪಡೆಯುತ್ತಾನೆ. ನಾವು ಯಾವುದೊ ಒಂದು ಫಲ ಕಾಮನೆಯಿಂದ ಕರ್ಮ ಮಾಡಿದರೆ\nಅದರಿಂದ ಯಾವುದೇ ಫಲ ಸಿಗುವುದಿಲ್ಲ ಎಂದಲ್ಲ. ಆದರೆ ಆ ಫಲ ನಮಗೆ ಎಷ್ಟು ಉಪಯುಕ್ತ ಎನ್ನುವ ಅರಿವು\nನಮಗೆ ಇರುವುದಿಲ್ಲ ಹಾಗೂ ಅದು ಪೂರ್ಣವಾದ ಫಲವಾಗಿರುವುದಿಲ್ಲ. ಫಲಕಾಮನೆ ಇಲ್ಲದೇ ಕರ್ಮ ಮಾಡಿದರೆ\nನಾವು ನಮಗೆ ಅಗತ್ಯವಾದ ಎಲ್ಲವನ್ನೂ ಪಡೆಯುತ್ತೇವೆ. ನಾವು ಕರ್ಮಫಲದ ಆಸೆ ಇಲ್ಲದೆ ಕರ್ಮದಲ್ಲಿ\nತೊಡಗಿಸಿಕೊಂಡರೆ, ಕರ್ಮದಲ್ಲೇ ಮುಂದುವರಿದು ಅದರಿಂದ ಜ್ಞಾನಪಡೆದು, ಅಂತಃಕರಣ ಶುದ್ಧಿಯಿಂದ\nಭಗವಂತನ ಅನುಗ್ರಹಕ್ಕೆ ಪಾತ್ರರಾಗಿ ಮೋಕ್ಷವನ್ನು ಪಡೆಯುಬಹುದು.\n\nಕರ್ಮಯೋಗವಿಲ್ಲದೆ 'ನನಗೋಸ್ಕರ ನಾನು ದುಡಿಯುತ್ತಿದ್ದೇನೆ, ಇದು ನನ್ನ ಸಂಪತ್ತು, ನಾನು ದುಡಿದದ್ದನ್ನು ನನ್ನ\nಸುಖಕ್ಕಾಗಿ ಖರ್ಚು ಮಾಡುತ್ತೇನೆ, ಯಾವ ದೇವರೂ ನಮಗೆ ಸಹಾಯ ಮಾಡುವುದಿಲ್ಲ ಇತ್ಯಾದಿ ಆತ್ಮ\nಕೇಂದ್ರಿತವಾದ ಭಾವನೆಯಿಂದ ಕರ್ಮ ಮಾಡಿದಾಗ ಕರ್ಮ ನಮಗೆ ಬಂಧಿಯಾಗುತ್ತದೆ. ಒಂದು ಮೂಕಪ್ರಾಣಿ\nಕೂಡಾ ಹೀಗೆ ಬದುಕುವುದಿಲ್ಲ. ಉದಾಹರಣೆಗೆ ಕಾಗೆ: ಅದಕ್ಕೆ ಒಂದು ತಿನ್ನುವ ವಸ್ತು ಕಾಣಿಸಿದರೆ, ತನ್ನೆಲ್ಲಾ\nಬಳಗವನ್ನು ಕರೆದು ಹಂಚಿಕೊಂಡು ತಿನ್ನುತ್ತದೆ. ಹುಲಿ-ಸಿಂಹಗಳಂತಹ ಕ್ರೂರ ಮೃಗಗಳೂ ಕೂಡಾ ಒಮ್ಮೆ\nತಮ್ಮ ಹೊಟ್ಟೆ ತುಂಬಿದ ಮೇಲೆ ಎಂದೂ ಸ್ವಾರ್ಥದಿಂದ ಕಾರ್ಯ ನಿರ್ವಹಿಸುವುದಿಲ್ಲ. ಆದರೆ ಮಾನವರಾದ\nನಾವು. ಸ್ವಾರ್ಥದಿಂದ ಬದುಕುತ್ತೇವೆ. ನಮಗೆ ಎಷ್ಟು ಪಡೆದರೂ ಮತ್ತಷ್ಟರಾಸೆ! ಈ ರೀತಿ ಬದುಕುವವನು\nಸಂಸಾರ ಚಕ್ರದಲ್ಲಿ ಸಿಕ್ಕಿ ಅಧೋಗತಿಯನ್ನು ಪಡೆಯುತ್ತಾನೆ.\n",
  "5.13": "ಸರ್ವ ಕರ್ಮಾಣಿ ಮನಸಾ ಸಂನ್ಯಸ್ಯ ಆಸ್ತೇ ಸುಖಮ್‌ ವಶೀ ।\n\nನವ ದ್ವಾರೇ ಪುರೇ ದೇಹೀ ನ ಏವ ಕುರ್ವನ್‌ ನ ಕಾರಯನ್‌-ಮಾನಸಿಕವಾಗಿ ಎಲ್ಲಾ ಕರ್ಮಗಳ ನಂಟು ತೊರೆದು\nಇಂದ್ರಿಯಗಳನ್ನು ಗೆದ್ದವನು ಹಾಯಾಗಿರುತ್ತಾನೆ-ಒಂಭತ್ತು ಬಾಗಿಲ ಈ ಪುರದಲ್ಲಿ; ಏನನ್ನೂ ಮಾಡದೆ, ಏನನ್ನೂ\nಮಾಡಿಸದೆ.\n\nಎಲ್ಲಾ ಕರ್ಮವನ್ನು ಮಾನಸಿಕವಾಗಿ ಸಂನ್ಯಾಸ ಮಾಡು ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಇದು ಬಹಳ ಮುಖ್ಯವಾದ ಮಾತು.\nಇಲ್ಲಿ 'ಕರ್ಮವನ್ನು ತ್ಯಾಗ ಮಾಡು' ಎಂದು ಕೃಷ್ಣ ಹೇಳುತ್ತಿಲ್ಲ, ಕೇವಲ ಮನಸ್ಸಿನಲ್ಲಿ ಬಿಡು ಎನ್ನುತ್ತಿದ್ದಾನೆ. ಅಂದರೆ\nಕರ್ಮಗಳ ಬಗ್ಗೆ ಮನಸ್ಸಿನಲ್ಲಿರುವ ಫಲದ ಸಂಗ; ಮಾನಸಿಕವಾಗಿ ಸ್ವಾತಂತ್ರ್ಯ ಎನ್ನುವ ಭ್ರಮೆಯನ್ನು ಬಿಡುವುದು.\n'ನನಗೆ', 'ಸನಗೋಸ್ಕರ' ಎನ್ನುವ ವಿಚಾರವನ್ನು ಮಾನಸಿಕವಾಗಿ ಬಿಡುವುದು. 'ಜೀವನಿಗೆ ಯಾವ ಕಾಲದಲ್ಲೂ\nಯಾವ ಕರ್ತ್ಯತ್ವದಲ್ಲೂ ಸ್ವಾತಂತ್ರ್ಯವಿಲ್ಲ. ಇದನ್ನು ಮಧ್ವಾಚಾರ್ಯರು ತಮ್ಮ ಎಲ್ಲಾ ಗ್ರಂಥಗಳಲ್ಲಿ ಸಾರಿ-ಸಾರಿ\nಹೇಳಿದ್ದಾರೆ. ಇದನ್ನು ಮಾನಸಿಕವಾಗಿ ಅಳವಡಿಸಿಕೊಳ್ಳುವುದೇ ನಿಜವಾದ ಕರ್ಮಸಂನ್ಯಾಸ.\n\nಭಗವಂತ ಈ ಒಂಭತ್ತು ಬಾಗಿಲಿನ ಪುರದೊಳಗೇ(ಪೂರ್ಣತೆಯನ್ನು ಪಡೆದ ಮನುಷ್ಯ ಶರೀರ) ನಮ್ಮನ್ನು ಕೂರಿಸಿ\nನಮ್ಮಿಂದ ಕರ್ಮ ಮಾಡಿಸುತ್ತಿದ್ದಾನೆ. 'ನನ್ನನ್ನು ಈ ಪುರದಲ್ಲಿಟ್ಟು, ನನ್ನೊಂದಿಗೆ ನನ್ನ ಆತ್ಮೀಯ ಗೆಳೆಯನಾಗಿ\nನಿಂತು, ನನ್ನ ಉದ್ಧಾರಕ್ಕಾಗಿ ಆ ಭಗವಂತ ಕರ್ಮ ಮಾಡಿಸುತ್ತಿದ್ದಾನೆ' ಎನ್ನುವ ಎಚ್ಚರ ಕರ್ಮಯೋಗ.\nಕರ್ಮಯೋಗದ ಬಗ್ಗೆ ಕೃಷ್ಣ ವಿವರಿಸಿದ ಅಪೂರ್ವವಾದ ಜ್ಞಾನಯೋಗವನ್ನು ನೋಡಿದೆವು. ಹೀಗೆ ಕರ್ಮ\nಮಾಡುವುದರಿಂದ ಅದು ಭಗವಂತನ ಆರಾಧನೆಯಾಗುತ್ತದೆ ಹಾಗೂ ಜ್ಞಾನಮಾರ್ಗದ ಒಂದು ಅಂಗವಾಗುತ್ತದೆ.\nಜ್ಞಾನದಿಂದ ಕರ್ಮ ಮಾಡಿದಾಗ ಯಾವ ಕ್ಷುದ್ರ ಕೆಲಸ ಕೂಡಾ ವ್ಯರ್ಥವಾಗುವುದಿಲ್ಲ, ಅದು ಯೋಗವಾಗುತ್ತದೆ.\nಇಲ್ಲಿ 'ಏನನ್ನೂ ಮಾಡದೆ, ಏನನ್ನೂ ಮಾಡಿಸದೆ' ಎಂದಿದ್ದಾನೆ ಕೃಷ್ಣ. ಸಾಮಾನ್ಯವಾಗಿ ನಾವು ಒಂದು ಕೆಲಸ\nಮಾಡಿದರೆ 'ಅದನ್ನು ನಾನು ಮಾಡಿದೆ', 'ನಾನು ಹೇಳಿದ್ದರಿಂದ ಆ ಕಾರ್ಯ ಆಯಿತು' ಎಂದು ಎಲ್ಲಾ ಕಡೆ\nಹೇಳಿಕೊಂಡು ಬರುತ್ತೇವೆ. ಹಾಗೆ ನಾಲ್ಕು ಜನ ಹೇಳಲಿ ಎಂದು ಬಯಸುತ್ತೇವೆ. ಆದರೆ ಜ್ಞಾನಿಗಳು ಹಾಗೆ\nಹೇಳುವುದಿಲ್ಲ. 'ಏನೋ ದೇವರು ನನ್ನ ಕೈಯಲ್ಲಿ ಮಾಡಿಸಿದ' , 'ನನ್ನೊಳಗಿದ್ದು ಆ ದೇವರು ಮಾಡಿಸಿದ',\n'ಭಗವಂತ ಅವರಿಗೆ ಪ್ರೇರಣೆ ಮಾಡಿದ' ಇತ್ಯಾದಿಯಾಗಿ ಮಾತನಾಡುತ್ತಾರೆ. ಇದಕ್ಕೆ ಕಾರಣ ಜ್ಞಾನಿಗಳು ಎಂದೂ\n'ನಾನು ಸ್ವತಂತ್ರ ಕರ್ತಾ' ಎನ್ನುವ ಪ್ರಜ್ಞೆಯನ್ನು ಬೆಳೆಸಿಕೊಂಡಿರುವುದಿಲ್ಲ. ಇದು ಜ್ಞಾನಿಗಳ ಮತ್ತು ಅಜ್ಞಾನಿಗಳ\nಕರ್ಮದ ಅನುಸಂಧಾನದಲ್ಲಿರುವ ವ್ಯತ್ಯಾಸ.\n\nಈ ಎಲ್ಲಾ ವಿಚಾರವನ್ನು ತಿಳಿದ ಮೇಲೆ ನಮಗೆ ಒಂದು ಪ್ರಶ್ನೆ ಮೂಡುತ್ತದೆ. ಎಲ್ಲವನ್ನೂ ದೇವರೇ\nಮಾಡಿಸುವುದಾದರೆ ಆತ ನಮ್ಮ ಕೈಯಲ್ಲಿ ಒಳ್ಳೆಯ ಕೆಲಸವನ್ನೇ ಮಾಡಿಸಲಿ, ಕೆಟ್ಟ ಕೆಲಸ ಏಕೆ ಮಾಡಿಸುತ್ತಾನೆ?\nಕೆಟ್ಟಕೆಲಸ ಮಾಡಿಸುವವ ಅವನೇ ಆದರೆ ನಮಗೇಕೆ ಅದರ ಶಿಕ್ಷೆ? ನಮಗೇಕೆ ದುಃಖ? ನಾನು ಬಯಸಿ\nಬುದ್ಧಿಪೂರ್ವಕವಾಗಿ ಮಾಡಿದಾಗ ನಾನು ಏಕೆ ಕರ್ತಾ ಅಲ್ಲ? ಅದರಿಂದ ಏಕೆ ನನಗೆ ಫಲ ಬರುವುದಿಲ್ಲ? ಎಲ್ಲಾ\nದೇವರೇ ಮಾಡಿಸುವುದಾದರೆ ನನಗೆ ಫಲ ಹೇಗೆ ಬರುತ್ತದೆ? ಇತ್ಯಾದಿ ಪ್ರಶ್ನೆ. ಇದು ಪ್ರತಿಯೊಬ್ಬರನ್ನೂ ಕಾಡುವ\nಪ್ರಶ್ನೆ. ಇವು ಕಾಡುವ ಪ್ರಶ್ನೆಗಳೇನೋ ಸರಿ ಆದರೆ ಸರಿಯಾದ ಪ್ರಶ್ನೆಗಳಲ್ಲ. ಶಾಸ್ತ್ರದ ತಿರುಳು ತಿಳಿಯದಾಗ ಈ\nಪ್ರಶ್ನೆಗಳು ಬರುತ್ತವೆ. ಮುಂದಿನ ಶ್ಲೋಕಗಳನ್ನು ಸೂಕ್ಷ್ಮವಾಗಿ ವಿಶ್ಲೇಷಿಸಿದರೆ ಈ ನಮ್ಮ ಪ್ರಶ್ನೆಗೆ ಉತ್ತರ\nಸಿಗುತ್ತದೆ.\n",
  "5.14": "ನ ಕರ್ತೃತ್ವಮ್‌ ನ ಕರ್ಮಾಣಿ ಲೋಕಸ್ಯ ಸೃಜತಿ ಪ್ರಭುಃ |\n\nನ ಕರ್ಮಫಲ ಸಂಯೋಗಮ್‌ ಸ್ವಭಾವಃ ತು ಪ್ರವರ್ತತೇ -- ಜೀವ ಜಡದಂತಲ್ಲ; ಕ್ರಿಯೆ ಮಾಡಬಲ್ಲ. ಆದರೂ\nಅವನು ಹೊಣೆಗಾರನಲ್ಲ- ಲೋಕದ ಯಾವ ಕ್ರಿಯೆಗೂ, ಪುಣ್ಯ-ಪಾಪಗಳಿಗೂ,ಅದರಿಂದೊದಗುವ ಫಲಕ್ಕೂ.\n(ಕ್ರಿಯೆಯ,ಪುಣ್ಯಪಾಪಗಳ, ಮತ್ತು ಕರ್ಮಫಲ ಪಡೆಯುವ ಒಡೆತನವನ್ನು ಜೀವಲೋಕಕ್ಕೆ ಭಗವಂತ ನೀಡಲಿಲ್ಲ].\nಜೀವದ ಸ್ವಭಾವ ತನ್ನ ಕೆಲಸ ಮಾಡುತ್ತಿರುತ್ತದೆ.ಭಗವಂತ ಈ ಎಲ್ಲವನ್ನೂ ಮಾಡುತ್ತಿರುತ್ತಾನೆ].\n\nಈ ಹಿಂದೆ ವಿಶ್ಲೇಷಿಸಿದ ಸಮಸ್ತ ಪ್ರಶ್ನೆಗಳಿಗೂ ಉತ್ತರ ಒಗಟಿನ ರೂಪದಲ್ಲಿ ಈ ಶ್ಲೋಕದಲ್ಲಡಗಿದೆ. ಮೇಲ್ನೋಟಕ್ಕೆ\nಇದು ತಿಳಿಯುವುದಿಲ್ಲ; ಶಾಸ್ತ್ರದ ಅನುಭಾವದಿಂದ ಒಂದೊಂದು ಶಬ್ದವನ್ನು ಮನನ ಮಾಡಿದಾಗ ಮಾತ್ರ ಅಲ್ಲಿ\nಉತ್ತರ ಸಿಗುತ್ತದೆ.\n\nಜಡಲೋಕಕ್ಕೆ ಜೀವ-ಪ್ರಭು, ಅದರಲ್ಲಿ ಇಚ್ಛಾಪೂರ್ವಕಕ್ರಿಯೆ ಇದೆ, ಆದರೆ ಅದು ಕರ್ತೃತ್ವವಲ್ಲ. ಜೀವವನ್ನು ಜಡಕ್ಕೆ\nಹೋಲಿಸಿದಾಗ: ಜಡಕ್ಕೆ ಯೋಚನೆ ಮಾಡುವ ಶಕ್ತಿ ಇಲ್ಲ-ಆದರೆ ಜೀವಕ್ಕೆ ಯೋಚನೆ ಮಾಡುವ ಶಕ್ತಿ ಇದೆ; ಜಡಕ್ಕೆ\nಬುದ್ಧಿ ಇಲ್ಲ-ಆದರೆ ಜೀವಕ್ಕಿದೆ; ಎರಡಕ್ಕೂ ಕರ್ತ್ಯತ್ವವಿಲ್ಲ. ಕ್ರಿಯೆಯ,ಪುಣ್ಯಪಾಪಗಳ, ಮತ್ತು ಕರ್ಮಫಲ ಪಡೆಯುವ\nಒಡೆತನವನ್ನು ಜೀವಲೋಕಕ್ಕೆ ಭಗವಂತ ನೀಡಿಲ್ಲ. ಜೀವನಿಗೆ ದತ್ತಸ್ವಾತಂತ್ರ್ಯ ಕೂಡಾ ಇಲ್ಲ. [ಉದಾಹರಣೆಗೆ:\nಒಬ್ಬ ರಾಜ ತನ್ನ ಮಗನಿಗೆ ದೇಶದ ಒಂದು ಭಾಗವನ್ನು ಸ್ವತಂತ್ರವಾಗಿ ಆಳುವ ಅಧಿಕಾರ ಕೊಡುವುದು\nದತ್ತಸ್ವಾತಂತ್ರ್ಯ]. ಕರ್ತೃತ್ವವನ್ನು ಸರಿಯಾಗಿ ತಿಳಿದುಕೊಳ್ಳಬೇಕಾದರೆ ಅದರ ಹಿಂದಿರುವ ಸ್ವಾರಸ್ಯವಾದ\nಶಾಸ್ತ್ರೀಯ ಪ್ರಕ್ರಿಯೆಯನ್ನು ತಿಳಿದುಕೊಳ್ಳಬೇಕು.\n\nಪ್ರಪಂಚದಲ್ಲಿ ಮೂರು ತರಹದ ಶಕರ್ತ್ಯತ್ವವಿದೆ. ಕೇವಲ ಕ್ರಿಯೆ ಇರುವುದೂ ಒಂದು ವಿಧದ ಕರ್ತೃತ್ವ. ಇದು\nಜಡಕ್ಕೂ ಇದೆ. ಉದಾಹರಣೆಗೆ 'ಕೆಚ್ಚಲು ಹಾಲು ಕೊಡುತ್ತದೆ'; ಇಲ್ಲಿ ಕೆಚ್ಚಲಿನಿಂದ ಹಾಲು ಸುರಿಯುವ ಕೃತಿ ಇದೆ\nಆದರೆ ಅದು ಅತ್ಯಂತ ಅಮುಖ್ಯವಾದ ಕರ್ತ್ಯತ್ವ. ಎರಡನೇಯದು ಬುದ್ಧಿ ಪೂರ್ವಕವಾದ ಕೃತಿ. ಸ್ವತಂತ್ರವಲ್ಲದ\nಇಚ್ಛಾಪೂರ್ವಕ ಕೃತಿ-ಇದು ಜೀವರಿಗಿದೆ, ಆದರೆ ನಿಜವಾದ ಪ್ರಮುಖ ಕರ್ತೃತ್ವ ಇದಲ್ಲ. ಸ್ವತಂತ್ರವಾದ\nಇಚ್ಛಾಪೂರ್ವಕ ಕ್ರಿಯೆ ನಿಜವಾದ ಕರ್ತೃತ್ವ. ಇದು ಇರುವುದು ಕೇವಲ ಭಗವಂತನಲ್ಲಿ ಮಾತ್ರ. ಜೀವನಿಗೆ\nಕರ್ಮದಲ್ಲಿ ದತ್ತಸ್ವಾತಂತ್ರ್ಯ ಕೂಡಾ ಇಲ್ಲ. ಜೀವ ಭಗವಂತನ ಪರಾಧೀನ. ಆದ್ದರಿಂದ ಆತ ಕರ್ತಾ ಅಲ್ಲ.\nಉದಾಹರಣೆಗೆ ತೊಟ್ಟಿಲಲ್ಲಿರುವ ಮಗು. ಅದಕ್ಕೆ ಬುದ್ಧಿ ಇದೆ, ತಿನ್ನಬೇಕು ಎನ್ನುವ ಇಚ್ಛೆ ಇದೆ, ಆದರೆ\nಸ್ವಾತಂತ್ರ್ಯವಿಲ್ಲ. ತಾಯಿ ಬಾಯಿಗಿಟ್ಟಿದ್ದನ್ನು ಅದು ತಿನ್ನುತ್ತದೆ. ಇದು ಇಚ್ಛಾಪೂರ್ಣ ಕ್ರಿಯೆ ಆದರೆ ಸ್ವತಂತ್ರ-\nಇಚ್ಛಾಪೂರ್ಣ ಕ್ರಿಯೆ ಅಲ್ಲ. ಇನ್ನು ಫಲದ ಬಗ್ಗೆ ಇದೇ ದೃಷ್ಟಾಂತದೊಂದಿಗೆ ನೋಡಿದಾಗ: ತಂದೆ-ತಾಯಿ\nಮಗುವಿಗೆ 'ದೇವರಿಗೆ ನಮಸ್ಕಾರ ಮಾಡು' ಎಂದು ಹೇಳುತ್ತಾರೆ, ಆಗ ಆ ಮಗು ಮಾಡುವುದಿಲ್ಲ, ಇಂತಹ\nಸಂದರ್ಭದಲ್ಲಿ ತಂದೆ. ತಾಯಿ, ಮಗುವನ್ನು ತಿದ್ದಿ-ತೀಡಿ. ಅಥವಾ ಅಗತ್ಯಬಿದ್ದರೆ ಶಿಕ್ಷಿಸಿ ದೇವರಿಗೆ\nನಮಸ್ಕರಿಸುವಂತೆ ಮಾಡುತ್ತಾರೆ, ಆಗ ಆ ಮಗು ಮಾಡುತ್ತದೆ. ಇಲ್ಲಿ ನಮಸ್ಕಾರ ಮಾಡಿಸಿದ್ದು ತಂದೆ-\n\nತಾಯಿಯಾದರೂ ಸಹ ಫಲ ಮಗುವಿಗೆ. ಇದೇ ರೀತಿ ಜೀವನೊಳಗೆ ಕುಳಿತ ಕಣ್ಣಿಗೆ ಕಾಣದ ಭಗವಂತ 'ಜೀವನ'\nಕ್ರಿಯೆಯನ್ನು ನಿಯಂತ್ರಿಸುತ್ತಾನೆ. ನಮ್ಮ ಮೂಲಕ ಕರ್ಮ ಮಾಡಿಸುವವನು ಭಗವಂತನಾದರೂ ಕೂಡಾ\nಕರ್ಮದ ಫಲ ನಮಗೇ ಹೊರತು ಭಗವಂತನಿಗಲ್ಲ.\n\nಈ ದೃಷ್ಟಾಂತದೊಂದಿಗೆ ಮುಂದುವರಿದಾಗ ನಮಗೆ ಇನ್ನೊಂದು ಪ್ರಶ್ನೆ ಕಾಡುತ್ತದೆ. “ಭಗವಂತ ನಮ್ಮ\nಮುಖೇನ ಏಕೆ ಕೆಟ್ಟ ಕೆಲಸ ಮಾಡಿಸುತ್ತಾನೆ? ತಂದೆ-ತಾಯಿ ಎಂದೂ ಮಗುವಿನಲ್ಲಿ ಕೆಟ್ಟ ಕೆಲಸ ಮಾಡಿಸುವುದಿಲ್ಲ,\nಅದೇ ರೀತಿ ಏಕೆ ಭಗವಂತ ನಮ್ಮಲ್ಲಿ ಕೇವಲ ಒಳ್ಳೆಯ ಕೆಲಸ ಮಾಡಿಸಬಾರದು?” ಎಂದು. ಇದು\nಲೋಕದಲ್ಲಿರುವುದಕ್ಕಿಂತ ವಿಲಕ್ಷಣವಾಗಿ ಕಾಣುವ ಕ್ರಿಯೆ. ಉದಾಹರಣೆಗೆ ಒಬ್ಬ ಉಪಾಧ್ಯಾಯ, ಆತ ತನ್ನ ಪಾಠ\nಪ್ರವಚನವನ್ನು ಎಲ್ಲಾ ಮಕ್ಕಳಿಗೂ ಒಂದೇ ರೀತಿಯಾಗಿ, ಭೇದ ಭಾವವಿಲ್ಲದೆ. ಕಲಿಸುತ್ತಾನೆ. ಆದರೆ ಒಬ್ಬ\nಪಾಠವನ್ನು ಬಹುಬೇಗ ಅರ್ಥ ಮಾಡಿಕೊಂಡರೆ ಇನ್ನೊ ಬ್ಬ ಅರ್ಥವಾಗದೇ ತಳಮಳಿಸಬಹುದು; ಮತ್ತೊಬ್ಬ\nಅಪಾರ್ಥ ಮಾಡಿಕೊಳ್ಳಬಹುದು. ಇದಕ್ಕೆ ಉಪಾಧ್ಯಾಯರು ಕಾರಣರಲ್ಲ, ಇದು ವಿಧ್ಯಾರ್ಥಿಯ ಸ್ವಭಾವಕ್ಕೆ\nಸಂಬಂಧಪಟ್ಟ ವಿಚಾರ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ \"ಸ್ವಭಾವಸ್ತು ಪ್ರವರ್ತತೇ\" ಎಂದು. ಇದು ಅಪೂರ್ವವಾದ ಸಂಗತಿ.\nಹಿಂದೆ ಹೇಳಿದಂತೆ ಜೀವ ಅನಾಧಿನಿತ್ಯ, ಅದನ್ನು ಭಗವಂತ ಸೃಷ್ಟಿ ಮಾಡಿಲ್ಲ. ಈ ಅನಾಧಿನಿತ್ಯವಾದ ಜೀವಕ್ಕೆ\nಅನಾಥಿನಿತ್ಯವಾದ ಒಂದು ಅಸಾಧಾರಣ ಸ್ವಭಾವವಿದೆ. ಆ ಸ್ವಭಾವದಂತೆ ಆ ಜೀವ\nನಡೆದುಕೊಳ್ಳುತ್ತದೆ.\n\nಜೀವಸ್ವಭಾವದಂತೆ ಜೀವ ನಡೆದುಕೊಳ್ಳುವುದು ಅಂದರೆ: ಉದಾಹರಣೆಗೆ ಮಾವಿನ ಬೀಜ, ಅದು ಮರವಾಗಿ\nಮಾವಿನ ಹಣ್ಣನ್ನೇ ಕೊಡುತ್ತದೆ ಹೊರತು ಹಲಸಿನ ಹಣ್ಣನ್ನಲ್ಲ, ಇದು ಆ ಬೀಜದ ಸ್ವಭಾವ. ಜೀವ ಎನ್ನುವುದು\nಶರೀರ ಎನ್ನುವ ವೃಕ್ಷದ ಬೀಜ. ಆ ಶರೀರದ ಮೂಲಕ ವ್ಯಕ್ತವಾಗುವುದು ಆ ಬೀಜದ ಮೂಲ ಗುಣವೇ ಹೊರತು\nಇನ್ನೆ ೀನೂ ಅಲ್ಲ. ಜೀವ ಮೊದಲನೆಯದಾಗಿ ತನ್ನ ಸ್ವಭಾವಕ್ಕೆ ಅಧೀನ. ನಾವು ನಮಗೆ ತೋಚಿದಂತೆ ಮಾಡಲು\nಸಾಧ್ಯವಿಲ್ಲ, ನಮ್ಮ ಸ್ವಭಾವ ಎಂತೋ ಅಂತೆಯೇ ನಮ್ಮ ತೀರ್ಮಾನ. ಮೂಲತಃ ನಿಜವಾದ ಸ್ವಭಾವದಂತೆ\nನಮ್ಮ ಅನಿಸಿಕೆ; ಅದಕ್ಕೆ ವಿರುದ್ಧವಾಗಿ ನಾವು ಕೆಲಸ ಮಾಡುವುದಿಲ್ಲ. ಈ ಕಾರಣದಿಂದ ಸ್ವಭಾವತಃ\nಸಾತ್ವಿಕನಾದರೆ ಆತನ ವಿಚಾರಧಾರೆಗಳೆಲ್ಲವೂ ಸಾತ್ವಿಕಗುಣದ ಪ್ರಭಾವದಲ್ಲೇ ಇರುತ್ತದೆ. ರಾಜಸನಾದವನ\nವಿಚಾರಧಾರೆ ರಾಜಸ ಗುಣದ ಪ್ರಭಾವದಲ್ಲಿರುತ್ತದೆ. ಸ್ವಭಾವದ ಜೊತೆಗೆ ಹುಟ್ಟಿ ಬೆಳೆದ ಸಮಾಜದ\nಪ್ರಭಾವವಿದ್ದರೂ ಸಹ ಅದರ ಅಭಿವ್ಯಕ್ತತೆ ಕ್ಷಣಿಕ. ಅದು ಹೆಚ್ಚೆಂದರೆ ಒಂದು ಜನ್ಮಕ್ಕೆ ಸೀಮಿತ, ಆದರೆ ಕೊನೆಗೆ\nಉಳಿಯುವುದು ಜೀವಸ್ವಭಾವ ಮಾತ್ರ.\n\nಜೀವಕ್ಕೆ ಅನಾಧಿನಿತ್ಯವಾಗಿ ಅಂಟಿದ ಸ್ವಭಾವ- ಸಾತ್ವಿಕ ರಾಜಸ ಮತ್ತು ತಾಮಸಗಳ ಸಮ್ಮಿಶ್ರಣ. ಸಾತ್ವಿಕರು\nಎಂದರೆ ಅವರಲ್ಲಿ ಸಾತ್ವಿಕ ಗುಣ ಪ್ರಮಾಣ ಹೆಚ್ಚು. ಯಾರಲ್ಲಿ ಯಾವ ಗುಣ ಪ್ರಧಾನವೋ ಆತ ಆ ಗುಂಪಿಗೆ\nಸೇರುತ್ತಾನೆ. ಈ ಮೂರು ವಿಧವಾದ ಜೀವಜಾತ ತನ್ನ ಸ್ವಭಾವಕ್ಕೆ ಅಧೀನವಾಗಿ ನಡೆದುಕೊಳ್ಳುತ್ತದೇ ಹೊರತು,\nತಾನು ಹೇಗೆ ಮಾಡಬೇಕು ಎಂದು ತೀರ್ಮಾನ ಮಾಡಿ ತನ್ನನ್ನು ರೂಪಿಸಿಕೊಳ್ಳುವ ಸ್ವತಂತ್ರ ಕರ್ತೃತ್ವ\nಅದಕ್ಕಿರುವುದಿಲ್ಲ.\n\nಸ್ವಭಾವ ನಮ್ಮ ಅಧೀನ ಅಲ್ಲ, ಅಂದಮೇಲೆ ಆ ಸ್ವಭಾವದ ಅಭಿವ್ಯಕ್ತಿ ನನ್ನ ಸ್ವಾತಂತ್ರ್ಯದಲ್ಲಿಲ್ಲ. ಮತ್ತೆ ಆ\nಸ್ವಭಾವದ ಅಭಿವ್ಯಕ್ತಿ ಹೇಗೆ? ಸ್ವಭಾವಕ್ಕೆ ತಕ್ಕಂತೆ ಬೆಳೆಯುವುದು ಯಾರ ಅಧೀನವಾಗಿ? ಸ್ವಭಾವಕ್ಕೆ ಆ ಶಕ್ತಿ\n\nಎಲ್ಲಿಂದ ಬಂತು? ಈ ಎಲ್ಲಾ ಪ್ರಶ್ನೆಗೆ ಇದೇ ಶ್ಲೋಕದಲ್ಲಿ ಉತ್ತರವಿದೆ. ಅದಕ್ಕಾಗಿ ನಾವು ಈ ಶ್ಲೋಕದಲ್ಲಿ\nಅಡಗಿರುವ ಇನ್ನೊಂದು ಅರ್ಥವನ್ನು ನೋಡಬೇಕು. ನಮಗೆ ಕರ್ತೃತ್ವವಿಲ್ಲ ಹಾಗೂ ಕರ್ಮದಲ್ಲಿ ಇಂತದ್ದೇ ಫಲ\nಬರಬೇಕು ಎನ್ನುವ ಸ್ವಾತಂತ್ರ್ಯವಿಲ್ಲ. ತಾನೇ ತಾನಾಗಿ ತನ್ನನ್ನು ಬಿತ್ತಿಕೊಂಡು ತಾನೇ ಮರವಾಗಿ ಬೆಳೆದು\nಹಣ್ಣನ್ನು ಕೊಡುವ ಶಕ್ತಿ ಜೀವಕ್ಕಿಲ್ಲ. ಸ್ವತಂತ್ರನಾದ ಭಗವಂತ ಸೃಷ್ಟಿ ಎನ್ನುವ ತೋಟ ನಿರ್ಮಿಸಿ, ಅಲ್ಲಿ ಒಬ್ಬ\nತೋಟಗಾರನಂತೆ, ಜೀವ ಎನ್ನುವ ಬೀಜವನ್ನು ಬಿತ್ತಿ ಬೆಳೆಸುತ್ತಾನೆ. ಅದರಿಂದ ನಮ್ಮ ದೇಹ ಎನ್ನುವ ಮರ\nಬೆಳೆಯುತ್ತದೆ ಮತ್ತು ಅದರಿಂದ ಕಹಿಯಾದ, ಹುಳಿಯಾದ ಅಥವಾ ಸಿಹಿಯಾದ ಹಣ್ಣು ಜೀವ ಸ್ವಭಾವದಂತೆ\nಅಭಿವ್ಯಕ್ತವಾಗುತ್ತದೆ. .. ಆದ್ದರಿಂದ ಕೆಟ್ಟಕೆಲಸ(ಕಹಿ) ಒಳ್ಳೆಯಕೆಲಸ(ಸಿಹಿ) ಎನ್ನುವುದು. ನಮ್ಮ\nಸ್ವಭಾವವನ್ನವಲಂಬಿಸಿದೆಯೇ ಹೊರತು ಭಗವಂತನನ್ನಲ್ಲ. ತೋಟಗಾರ ಎಂದೂ ಮೆಣಸಿನ ಗಿಡಕ್ಕೆ ಖಾರವಾದ\nನೀರನ್ನು ಹರಿಸುವುದಿಲ್ಲ. ಎಲ್ಲಾ ಗಿಡದಂತೆ ಆ ಗಿಡವನ್ನೂ ಪೋಷಿಸಿ ಬೆಳೆಸುತ್ತಾನೆ. ಆದರೆ ಅದು ಖಾರವಾದ\nಹಣ್ಣನ್ನು ತನ್ನ ಸ್ವಭಾವದಂತೆ ಕೊಡುತ್ತದೆ. ಹಾಗೇ ಭಗವಂತ ಅನಾಧಿನಿತ್ಯವಾದ ಜೀವದ ಸ್ವಭಾವಕ್ಕೆ ತಕ್ಕಂತೆ\nಕ್ರಿಯೆ ಮಾಡಿಸಿದ ಹಾಗೇ ಕ್ರಿಯೆ ನಡೆಯಿತು.\n\nಕೆಲವೊಮ್ಮೆ ನಾವು ಯೋಚಿಸಿದ್ದಕ್ಕೆ ವಿರುದ್ಧವಾಗಿ ಕೆಲಸ ಮಾಡುತ್ತೇವೆ. ಏಕೆಂದರೆ ನಮ್ಮ ಮನಸ್ಸು ಮತ್ತು\nಬುದ್ಧಿಯ ವಿಚಾರ ಸರಣಿ(",
  "5.15": "ನ ಆದತ್ತೇ ಕಸ್ಯಚಿತ್‌ ಪಾಪಮ್‌ ನ ಚ ಏವ ಸುಕೃತಮ್‌ ವಿಭುಃ ।\n\nಅಜ್ಞಾನೇನ ಆವೃತಮ್‌ ಜ್ಞಾನಮ್‌ ತೇನ ಮುಹ್ಯಂತಿ ಜಂತವಃ -ಜಡಕ್ಕಿಂತ ಮಿಗಿಲೆನಿಸಿದ ಜೀವ ಯಾರ\nಪಾಪವನ್ನೂ ತೊಡೆಯಲಾರ; ಪುಣ್ಯವನ್ನು ಕೂಡಾ. [ಯಾವ ಜೀವಿಯ ಪಾಪ-ಪುಣ್ಯಗಳ ನಂಟೂ\nಭಗವಂತನಿಗಿಲ್ಲ.]ಅರಿವಿಗೆ ಅವಿದ್ಯೆಯ ಮುಸುಕಿದೆ. ಅದರಿಂದ ಜನರು ಮೈಮರೆಯುತ್ತಾರೆ.\n\nಈ ಶ್ಲೋಕವನ್ನು 'ಜೀವದ' ಪರವಾಗಿ ಮತ್ತು 'ಭಗವಂತ'ನ ಪರವಾಗಿ ಎರಡು ರೂಪದಲ್ಲಿ ನೋಡಬಹುದು.\n'ಜೀವದ' ಪರದಲ್ಲಿ ನೋಡಿದಾಗ ವಿಭುಃ ಎನ್ನುವ ಪದ ವಿಶಿಷ್ಟ, ವೈವಿಧ್ಯ, ವಿವಿಧ ಇತ್ಯಾದಿ ಅರ್ಥವನ್ನು ಕೊಡುತ್ತದೆ.\nಜಡಕ್ಕಿಂತ ವಿಶಿಷ್ಟನಾಗಿ-ಇಚ್ಛೆ, ಯೋಚನೆ, ಜ್ಞಾನ ಇರುವ ಜೀವ ವಿಶಿಷ್ಟ. ಬೇರೆಬೇರೆ ಜನ್ಮದಲ್ಲಿ ಬೇರೆಬೇರೆ\nಜೀವಿಯಾಗಿ ಹುಟ್ಟಬಹುದಾದ ಜೀವ, ಒಂದು ಜನ್ಮದಲ್ಲೇ ಅನೇಕ ವೈವಿಧ್ಯತೆಯನ್ನು ಕಾಣಬಹುದು.\nಉದಾಹರಣೆಗೆ: ಮನುಷ್ಯನಾದವನು. ಶ್ರೀಮಂತನಾಗಿ ಸುಖದ ಸುಪ್ಪತ್ತಿಗೆಯಲ್ಲಿ ಬದುಕಬಹುದು,\nದಾರಿದ್ರ್ಯದಲ್ಲಿರಬಹುದು. ದೊಡ್ಡ ವಿದ್ವಾಂಸನಾಗಿ ಬದುಕಬಹುದು ಅಥವಾ ಏನೂ ಅರಿವಿಲ್ಲದ ಮೂಢನಾಗಿ\nಬದುಕಬಹುದು. ಈ ರೀತಿಯ ವೈವಿದ್ಯತೆ ಜೀವದಲ್ಲಿದೆ-ಅದಕ್ಕಾಗಿ ಜೀವ ವಿಭುಃ. ಒಂದೇ ಜನ್ಮದಲ್ಲಿ ಹುಟ್ಟಿ\nಸಾಯುವ ತನಕ ಅನೇಕ ಮಜಲುಗಳಲ್ಲಿ ಅನೇಕ ವೈವಿಧ್ಯತೆಯನ್ನು ನಾವು. ಅನುಭವಿಸಬಹುದು.\n\nಶ್ರೀಮಂತನಾಗಿದ್ದವನು ಎಲ್ಲವನ್ನೂ ಕಳೆದುಕೊಂಡು ದಾರಿದ್ರ್ಯವನ್ನು ಪಡೆಯಬಹುದು. ಹೀಗಾದಾಗ ನಾವು ಅದರ\nಹಿಂದೆ ಏನೇನೋ ಕಾರಣಗಳನ್ನು ಹುಡುಕುತ್ತೇವೆ. ಸಾಮಾನ್ಯವಾಗಿ ನಾವು ಮಾಡುವ ಮೊದಲ ಕೆಲಸ\nಯಾವುದೋ ಜ್ಯೋತಿಷಿಗಳಲ್ಲಿ ಹೋಗಿ ಪ್ರಶ್ನೆ ಹಾಕುವುದು. ಹಾಗೆ ಕೇಳಿದಾಗ ಅವರು ಯಾರೋ\nವಾಮಾಚಾರ ಮಾಡಿದ್ದರಿಂದ ನೀನು ನಷ್ಟ ಅನುಭವಿಸುತ್ತಿರುವುದು ಇತ್ಯಾದಿಯಾಗಿ ಹೇಳುತ್ತಾರೆ.\nಆದರೆ ಇಲ್ಲಿ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: \"ಯಾರ ಪಾಪವನ್ನೂ ನೀನು ತೆಗೆದುಕೊಳ್ಳಲು ಬರುವುದಿಲ್ಲ ಹಾಗೂ ಇನ್ನೊ ಬ್ಬರ\nಪುಣ್ಯ ನಮಗೆ ಸಿಗುವುದಿಲ್ಲ. ನಾವು ಏನು ಅನುಭವಿಸುತ್ತೇವೇ ಅದು ನಾವು ಮಾಡಿದ ಕರ್ಮಫಲ” ಎಂದು. ಈ\nಕಾರಣದಿಂದ ಇನ್ನೊಬ್ಬರಿಂದ ನಾವು ಹಾಳಾದೆವು ಎಂದು ತಿಳಿಯುವುದು ತಪ್ಪು ಎನ್ನುವುದು ಇಲ್ಲಿ ಸ್ಪಷ್ಟ.\nಹಾಗಿದ್ದರೆ ವಾಮಾಚಾರ ಇತ್ಯಾದಿ ಮಾಡಲು ಬರುವುದಿಲ್ಲವೋ, ಅದರಿಂದ ತೊಂದರೆ ಆಗುವುದು ಸುಳ್ಳೋ,\nಎಂದರೆ -ನಮ್ಮ ಸುಕೃತದ ಫಲ ನಮ್ಮನ್ನು ರಕ್ಷಣೆ ಮಾಡುವಷ್ಟು ಕಾಲ ಯಾವ ವಾಮಾಚಾರವೂ ನಮ್ಮನ್ನು\nಏನೂ ಮಾಡುವುದಿಲ್ಲ. ಇದನ್ನು ಜ್ಯೋತಿಷಿಗಳು \"ನಿಮ್ಮ ಗ್ರಹಗತಿ ಚೆನ್ನಾಗಿತ್ತು ಆದ್ದರಿಂದ ಈವರೆಗೆ ಏನೂ\nಆಗಿಲ್ಲ, ಆದರೆ ಈಗ ಅದು ಕೆಟ್ಟಿದೆ” ಇತ್ಯಾದಿಯಾಗಿ ಹೇಳುತ್ತಾರೆ. ಇಲ್ಲಿ ಗ್ರಹಗತಿ ಕೆಟ್ಟಿದೆ ಎಂದರೆ ನಮ್ಮ ಪಾಪದ\nಫಲ ಪಕ್ಚವಾಗಿದೆ ಎಂದರ್ಥ. ಆದ್ದರಿಂದ ಯಾರು ನಮ್ಮ ಮೇಲೆ ಕೃತ್ರಿಮ ಪ್ರಯೋಗ ಮಾಡಿದರೂ, ಅದರಿಂದ\nನಮಗೆ ಅನಿಷ್ಠವಾಗಬೇಕಾದರೆ ನಾವು ಹಿಂದೆ ಅನಿಷ್ಠಕರ್ಮ ಮಾಡಿರಬೇಕು. ಅದರ ಫಲವಾಗಿ ಇಲ್ಲಿ ನಮಗೆ ಅದು\nಅನುಭವಕ್ಕೆ ಬರುತ್ತದೆ. ನಮ್ಮ ದೋಷಗಳು, ನಮ್ಮ ಬಡತನ, ನಮ್ಮ ಅಜ್ಞಾನ, ರೋಗ-ರುಜಿನ ಇತ್ಯಾದಿಗಳಿಗೆ\nಇನ್ನೊ ಬ್ಬ ರನ್ನು ತೋರಿಸುವುದು, ಅವರಿಂದ ಹೀಗಾಯ್ತು ಎನ್ನುವುದು ತಪ್ಪು. ನಮಗೆ ರೋಗ ಉಲ್ಬಣವಾಗಿ\nಅದನ್ನು ಅನುಭವಿಸುವ ಪ್ರರಾಬ್ಧಕರ್ಮ ಇದ್ದರೆ ಅದನ್ನು ಯಾರಿಂದಲೂ ತಪ್ಪಿ ಸಲು ಬರುವುದಿಲ್ಲ. ಇದಕ್ಕಾಗಿ\nಇನ್ನೊಬ್ಬರ ಮೇಲೆ ಗೂಬೆ ಕೂರಿಸುವುದು ತಪ್ಪು. ಯಾರೋ ಮಾಡಿದ ಪಾಪಕರ್ಮದ ಫಲವನ್ನು ನಾನು\nಅನುಭವಿಸುವುದಿಲ್ಲ. ನಾನು ಮಾಡಿದ ಪಾಪ ಕರ್ಮದ ಫಲವನ್ನೇ ನಾನು ಅನುಭವಿಸುವುದು.\n\nಭಕ್ತನ ಪರ ಪುರೋಹಿತ ಮಾಡುವ ಕರ್ಮ ಭಕ್ತನಿಗೆ ಬರುತ್ತದೆ; ತಂದೆಯ ಪರ ಮಗ ಮಾಡುವ ಕರ್ಮ ತಂದೆಗೆ\nಬರಬಹುದು... ಇದು. ಒಬ್ಬರ ಪರ ಇನ್ನೊಬ್ಬರು. ಮಾಡಿದ ಕರ್ಮ. ಈ ಏಚಾರವನ್ನು\nಹೊರತುಪಡಿಸಿದರೆ ನಾವು ಅನುಭವಿಸುವುದು ನಾವೇ ಮಾಡಿದ ಕರ್ಮಫಲವೇ ಹೊರತು\nಇನ್ನೊಬ್ಬರದ್ದಲ್ಲ.\n\nಜನರಿಗೆ ಸರಿಯಾದ ಅರಿವಿಲ್ಲದ ಕಾರಣ 'ಇನ್ನೊಬ್ಬರಿಂದ ನನಗೆ ತೊಂದರೆ ಆಯ್ತು' ಎಂದು ತಿಳಿಯುತ್ತಾರೆ.\nಇದಕ್ಕೆಲ್ಲಾ ಮೂಲಕಾರಣ ಕರ್ಮದ ಬಗ್ಗೆ, ಜೀವದಬಗ್ಗೆ, ಪರಮಾತ್ಮನ ಬಗ್ಗೆ ಸರಿಯಾದ ಅರಿವು ಇಲ್ಲದಿರುವುದು.\nಜ್ಞಾನವೆನ್ನುವುದು ಅಜ್ಞಾನದ ಮುಸುಕಿನಲ್ಲಿ ಮುಚ್ಚಿಹೋಗಿ ಅದರಿಂದ ತಪ್ಪು ತಿಳುವಳಿಕೆ ಹಾಗೂ ಮೋಹದ\nಭ್ರಾಂತಿ ನಮ್ಮನ್ನು ಆವರಿಸಿರುವುದು.\n\nಈ ಶ್ಲೋಕದ ಇನ್ನೊಂದು ಮುಖ ನೋಡಿದರೆ 'ವಿಭುಃ ಅಂದರೆ ಸರ್ವಸಮರ್ಥನಾದ, ಸರ್ವಗತನಾದ\nಭಗವಂತ. ಈ ಅರ್ಥದಲ್ಲಿ ನೋಡಿದಾಗ: ಭಗವಂತನಿಗೆ ಯಾವ ಕರ್ಮದ ಲೇಪವೂ ಇಲ್ಲ. ಆತ ಜೀವ\nಸ್ವರೂಪದಲ್ಲಿನ ಅಂತರವನ್ನು ಗುರುತಿಸಿ ಅದಕ್ಕೆ ತಕ್ಕಂತೆಯೇ ಬೆಳವಣಿಗೆಯನ್ನು ಕೊಡುತ್ತಾನೆ. ಆತ ಎಂದೂ\n\nಪಕ್ಷಪಾತಿ ಅಲ್ಲ. ಪಾಪ-ಪುಣ್ಯ ಎರಡರ ಲೇಪವೂ\n\nಆತನಿಗಿಲ್ಲ. ಆದರೆ ಭಗವಂತನ ಈ ಕರ್ಮಸಿದ್ಧಾಂತ, ಆತನ ಸರ್ವಸಮರ್ಥತೆ, ಮತ್ತು ಅವನ ನಿರ್ಲಿಪ್ತತೆ, ಇದರ\nಅರಿವು ಬಹಳ ಜನಕ್ಕೆ ತಿಳಿದಿಲ್ಲ-ಆದ್ದರಿಂದ ಭಗವಂತನ ಬಗೆಗೆ ಗೊಂದಲಕ್ಕೊಳಗಾಗುತ್ತಾರೆ.\n\n'ನಮಗೆ ಸ್ವತಂತ್ರವಾದ ಕರ್ತ್ಯತ್ವವಿಲ್ಲ, ನಾವು ಆತನ ಅಧೀನ' ಎನ್ನುವ ವಿಚಾರದಲ್ಲಿ ನಾವು ಸದಾ\nಗೊಂದಲಕ್ಕೊಳಗಾಗುತ್ತೇವೆ. ಎಲ್ಲವನ್ನೂ ಭಗವಂತನೇ ಮಾಡುವುದಾದರೆ ಪಾಪ ಕರ್ಮಗಳು ನಮಗೇಕೆ\nಅನ್ನುವ ಪ್ರಶ್ನೆ ಹೆಚ್ಚಿನವರನ್ನು ಕಾಡುತ್ತದೆ. ಎಷ್ಟು ಅಧ್ಯಯನ ಮಾಡಿದರೂ ಈ ಕರ್ಮಸಿದ್ಧಾಂತ\nಅರ್ಥವಾಗುವುದಿಲ್ಲ. ಇದಕ್ಕೆ ಕಾರಣ ಅರಿವಿನ ಅಭಾವ. ಈ ಅರಿವು ಕೇವಲ ಓದುವುದರಿಂದ ಬರುವುದಿಲ್ಲ.\nಅದನ್ನು ಗ್ರಹಿಸಿ-ಗ್ರಹಿಸಿ, ಅನುಭವಿಸಿ ಮನವರಿಕೆ ಮಾಡಿಕೊಳ್ಳಬೇಕು. ಇದನ್ನು ಕೃಷ್ಣ ಯಾವುದೇ ಗೊಂದಲಕ್ಕೆ\nಅವಕಾಶವಿಲ್ಲದಂತೆ ಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ವಿವರಿಸಿದ್ದಾನೆ.\n\nಜ್ಞಾನೇನ ತು ತದಜ್ಞಾನಂ ಯೇಷಾಂ ನಾಶಿತಮಾತ್ಮನಃ |\nತೇಷಾಮಾದಿತ್ಯವಜ್‌ ಜ್ಞಾನಂ ಪ್ರಕಾಶಯತಿ ತತ್‌ ಪರಮ್‌ ॥೧೬॥\n\nಜ್ಞಾನೇನ ತು ತತ್‌ ಅಜ್ಞಾನಮ್‌ ಯೇಷಾಮ್‌ ನಾಶಿತಮ್‌ ಆತ್ಮನಃ |\nತೇಷಾಮ್‌ ಆದಿತ್ಯ ವತ್‌ ಜ್ಞಾನಮ್‌ ಪ್ರಕಾಶಯತಿ ತತ್‌ ಪರಮ್‌-ಭಗವಂತನ ಅರಿವಿನಿಂದ ಅವಿದ್ಯೆಯನ್ನು\nಅಳಿಸಿಕೊಂಡವರ ಆ ಅರಿವು-ಸೂರ್ಯನಂತೆ ಪರತತ್ವವನ್ನು ಬೆಳಗಿಸುತ್ತದೆ.\n\nನಾವು ನಮ್ಮ ಗೊಂದಲವನ್ನು ಪರಿಹರಿಸಿಕೊಳ್ಳಲು ಇರುವುದು ಕೇವಲ ಒಂದೇ ಮಾರ್ಗ. ಜ್ಞಾನ ಮಾರ್ಗದಲ್ಲಿ\nಸಾಧನೆ ಮಾಡಿ ಸತ್ಯವನ್ನು ತಿಳಿದುಕೊಳ್ಳುವುದು. ನಮ್ಮ ಸಮಸ್ಯೆ ಅಂದರೆ ನಮ್ಮೊಳಗೆ ಇರುವ ಜೀವ\nಸ್ವರೂಪದಲ್ಲಿ ಜ್ಞಾನವಿದೆ-ಆದರೆ ಅದನ್ನು ಅಜ್ಞಾನವೆಂಬ ಮಸುಕು ಕವಿದಿದೆ. ನಾವು ನಮ್ಮ ಜೀವ ಸ್ವರೂಪವನ್ನು\nಅಜ್ಞಾನವೆಂಬ ಪೆಟ್ಟಿಗೆಯೊಳಗೆ ಭದ್ರವಾಗಿ ಮುಚ್ಚಿಟ್ಟಿದ್ದೇವೆ. ಜ್ಞಾನಕ್ಕೆ ಮುಚ್ಚಳ-ಅಜ್ಞಾನದ್ದು ಹಾಗೂ ನಮಗೆ ಆ\nಮುಚ್ಚಳವನ್ನು ತೆಗೆಯಲು ಇಷ್ಟವಿಲ್ಲ.\n\nನಾವು. ಮೊದಲು ತಿಳಿಯಬೇಕಾದ ಸಂಗತಿ 'ನಾನು ಅಂದರೆ ಏನು' ಎನ್ನುವುದನ್ನು. ಅದು ಗೊತ್ತಾದಾಗ ನನ್ನ\nಸೀಮಿತತೆ ಏನು, ನನ್ನ ಶಕ್ತಿ ಏನು, ನನ್ನ ಅಲ್ಪತ್ವವೇನು ಎನ್ನುವುದು ತಿಳಿಯುತ್ತದೆ. ನಮ್ಮ ಇಂದ್ರಿಯದ ಒಡೆತನ\nನಮಗಿಲ್ಲ; ನಮ್ಮ ಮನಸ್ಸು ನಾವು ಹೇಳಿದಂತೆ ಕೇಳುವುದಿಲ್ಲ. ಆದ್ದರಿಂದ ನಾನು ಇವೆಲ್ಲವುದರ ಜೊತೆಗಿದ್ದೇನೆ,\nಯಾರೋ ಇದನ್ನೆ ಲ್ಲಾ ಇಲ್ಲಿ ಇಟ್ಟಿ ದ್ದಾರೆ; ಇಂದ್ರಿಯದಿಂದ ಅನುಭವ ಬರುತ್ತದೆ ನಾನು ಅನುಭವಿಸುತ್ತೇನೆ ಎನ್ನು ವ\nಅರಿವು ಮೂಡುತ್ತದೆ... ಈ ಇಂದ್ರಿಯಗಳನ್ನು ಕೊಟ್ಟವನ್ಯಾರು, ಅದರಿಂದ ಅನುಭವ ಕೊಡುವವನ್ಯಾರು\nಎನ್ನುವುದು ಅರ್ಥವಾದಾಗ, ತಾನು ಕೇವಲ ಪ್ರತಿಬಿಂಬ ಮತ್ತು ಮೂಲ ಬಿಂಬ ಭಗವಂತ ಎನ್ನುವ ಅರಿವು\nಮೂಡುತ್ತದೆ.\n\nನಾವು ಹೇಗೆ ನಮ್ಮ ಅಜ್ಞಾನದ ಪರದೆಯನ್ನು ಕಳಚಿ ಜ್ಞಾನದ ಮಾರ್ಗವನ್ನು ಹಿಡಿಯಬಹುದು ಎನ್ನುವುದನ್ನು ಕೃಷ್ಣ\nಇಲ್ಲಿ ವಿವರಿಸಿದ್ದಾನೆ. \"ಜ್ಞಾನ ಎನ್ನುವುದು ಬೆಂಕಿಯಂತೆ. ಒಳಗಿರುವ ಜ್ಞಾನದ ಕಿಡಿಯನ್ನು ಸತತ ಅಂತರಂಗದ\nಮನನದಿಂದ ಪ್ರಜ್ವಲಿಸು. ಆಗ ಅದು ಈ ಅಜ್ಞಾನವೆಂಬ ಪರದೆಯನ್ನು ಸುಟ್ಟುಬಿಡುತ್ತದೆ\". ನಿರಂತರ\nಅಂತರಂಗದ ಮನನ ಮಾತ್ರ ನಮ್ಮ ಅಂತರಂಗದ ಜ್ಞಾನವನ್ನು ಪ್ರಜ್ವಲಿಸಬಲ್ಲದು. ಹೊರಗಿನ ಶ್ರವಣ,\nಅಧ್ಯಯನ ಇದಕ್ಕೆ ಪೂರಕ. ಒಮ್ಮೆ ಅಜ್ಞಾನದ ಪರದೆ ಸುಟ್ಟು ನಾಶವಾದಾಗ ನಮಗೆ ಸತ್ಯದ\nಸಾಕ್ಷಾತ್ಕಾರವಾಗುತ್ತದೆ. ಇದರಿಂದ 'ನಾನು ಮಾಡಿದೆ' ಎನ್ನುವ ಅಹಂಕಾರ ಬರಲು ಸಾಧ್ಯವೇ ಇಲ್ಲ. ಈ ಜ್ಞಾನದ\nಬೆಂಕಿ ಸೂರ್ಯ ಪ್ರಕಾಶಕ್ಕಿಂತ ದೊಡ್ಡದು ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಹೇಗೆ ಹೊರ ಪ್ರಪಂಚವನ್ನು ಸೂರ್ಯ\nಬೆಳಗಿಸುತ್ತಾನೋ ಹಾಗೇ ಈ ಜ್ಞಾನ ಅಂತರಂಗ ಪ್ರಪಂಚವನ್ನು ಬೆಳಗಿಸುತ್ತದೆ. ಇದು ಅಪರೋಕ್ಷ ಜ್ಞಾನ\nಹಾಗೂ ಈ ಜ್ಞಾನ ಭಗವಂತನ ಸಾಕ್ಷಾತ್ಕಾರ ಮಾಡಿಸುತ್ತದೆ.\n\nಕೃಷ್ಣನ ಈ ವಿವರಣೆಯನ್ನು ಕೇಳಿದಾಗ ನಮಗೆ ನಾವೂ ಅಪರೋಕ್ಷ ಜ್ಞಾನವನ್ನು ಪಡೆಯಬೇಕು ಅನ್ನಿ ಸುತ್ತದೆ.\nಆದರೆ ಅದು ಹೇಗೆ? ಅಪರೋಕ್ಷ ಜ್ಞಾನ ಬರಬೇಕಾದರೆ ನಾವು. ಏನು ಮಾಡಬೇಕು? ಇದನ್ನು ಮುಂದಿನ\nಶ್ಲೋಕದಲ್ಲಿ ಕೃಷ್ಣ ವಿವರಿಸಿದ್ದಾನೆ.\n\nತದ್‌ ಬುದ್ಧಯಸ್ತದಾತ್ಮಾನಸ್ತನ್ನಿಷ್ಠಾಸ್ತತ್‌ ಪರಾಯಣಾಃ |\nಗಚ್ಛಂತ್ಯ ಪುನರಾ",
  "5.16": "ಬೇರೆ, ನಾವು ಮಾಡುವುದು ಬೇರೆ. ಈ ಕಾರಣಕ್ಕಾಗಿ\nಕೆಲವರು ಹೊರಗಿನಿಂದ ಒಂದು ಮಾತನಾಡಿ ಒಳಗಿನಿಂದ ಅದಕ್ಕೆ ವ್ಯತಿರಿಕ್ತವಾದದ್ದನ್ನು ಮಾಡುತ್ತಾರೆ.\nದುರ್ಯೋಧನ ಕೂಡಾ \"ನಾನು ಮಾಡುತ್ತಾ ಇರುವುದು ತಪ್ಪು ಎನ್ನುವುದು ನನಗೆ ತಿಳಿದಿದೆ\" ಎಂದು\nಹೇಳಿರುವುದನ್ನು ಇಲ್ಲಿ ನಾವು ಗಮನಿಸಬೇಕು. ಆತನಿಗೆ ಧರ್ಮ ಯಾವುದು ಎಂದು ತಿಳಿದಿತ್ತು. ಆದರೂ ಆತ\nತನ್ನ ಸ್ವಭಾವದಂತೆ ನಡೆದ. ಆದ್ದರಿಂದ ನಮ್ಮ ತಿಳುವಳಿಕೆ ಬೇರೆ, ನಮ್ಮ ಕ್ರಿಯೆ ಬೇರೆ. ನಮ್ಮ ಸ್ವಭಾವ ನಮ್ಮೆಲ್ಲಾ\nಅಧ್ಯಯನ, ಬುದ್ಧಿ, ವಿಚಾರವಾದವನ್ನು ಬದಿಗೊತ್ತಿ ನಮ್ಮಿಂದ ಸ್ವಭಾವಕ್ಕನುಗುಣವಾದ ಕೆಲಸವನ್ನು ಮಾಡಿಸಿ\nಬಿಡುತ್ತದೆ. ಇದನ್ನೇ ಕೃಷ್ಣ ಇಲ್ಲಿ \" ಸ್ವಭಾವಸ್ತು ಪ್ರವರ್ತತೇ\" ಎಂದಿರುವುದು. ನಿನ್ನ ಸ್ವಭಾವ ಎಂತಹದ್ದೋ-\nಅಂತಹದ್ದೇ ನಿನ್ನ ಪ್ರವೃತ್ತಿ. ಅದಕ್ಕನುಗುಣವಾಗಿ ಭಗವಂತ ನಿನ್ನನ್ನು ಬೆಳೆಸುತ್ತಾನೆ. ಯಾರಲ್ಲಿ ಯಾವ\nಸ್ವಭಾವವಿದೆಯೋ ಅದೇ ರೀತಿ ಅವರಿರಬೇಕೇ ಹೊರತು ಇನ್ನೊ ಬ್ಬರಂತಲ್ಲ. ಮಾವಿನ ಹಣ್ಣು ಹುಳಿಯಾದರೆ\nಅದು ಕೆಟ್ಟ ಹಣ್ಣು, ಅದೇ ಹುಣಸೆ ಹಣ್ಣು ಹೆಚ್ಚು ಹುಳಿಯಾದಂತೆ ಹೆಚ್ಚು ಉತ್ತಮ. ಆದ್ದರಿಂದ ತಾಮಸರು\nತಾಮಸರಂತಿರುವುದು ಅವರ ಸಹಜ ಧರ್ಮ. ಯಾರ್ಯಾರ ಸಹಜ ಸ್ವಭಾವ ಎಂತದ್ದೋ ಅಂತೆಯೇ ಸಹಜ\nಸ್ವಭಾವದಲ್ಲಿ ಬೆಳೆಸುವ ಕ್ರಿಯೆಯನ್ನು ಸ್ವತಂತ್ರನಾದ ಭಗವಂತ ಮಾಡಿದ. ಎಲ್ಲವುದರ ಫಲವನ್ನು\nಕೊಡುವವನೂ ಅವನೇ. ಅವನಿಗೆ ಎಂದೂ ಬಂಧನವಿಲ್ಲ.\n\nಹೀಗೆ ಈ ಶ್ಲೋಕ ನಮ್ಮೆಲ್ಲಾ ಸಂಶಯಗಳಿಗೆ ಉತ್ತರರೂಪದಲ್ಲಿದೆ. ನಮ್ಮ ಸಂಶಯ ಅತ್ಯಂತ ಗಾಢ. ಮನಸ್ಸಿಗೆ\nಬರುವ ಸಂಶಯವನ್ನು ನಿವಾರಿಸಬಹುದು ಆದರೆ ಬುದ್ಧಿಗೆ ಬರುವ ಸಂಶಯವನ್ನು\nನಿವಾರಿಸುವುದು ಕಷ್ಟ. ಪ್ರಾಚೀನ ಶಾಸ್ತ್ರಕಾರರು ಮನಃಶಾಸ್ತ್ರದ ಪ್ರಕಾರ ಇದನ್ನು 'ಸ್ಥಿರಸಂಶಯ' ಎಂದು\nಕರೆದರು. ನಮ್ಮಲ್ಲಿರುವ ಭೌತಿಕ ಕೊಳೆ ಜಗತ್ತಿನಲ್ಲಿ 'ಎಲ್ಲರಿಗಿಂತ ನಾನು ಬುದ್ಧಿವಂತ' ಎಂದು\nತಿಳಿದುಕೊಳ್ಳುವಂತೆ ಮಾಡುತ್ತದೆ. ಇದರಿಂದ ನಾವು ಸತ್ಯದ ಕಡೆಗೆ ಮನಸ್ಸನ್ನು ಒಗ್ಗಿಸಿಕೊಳ್ಳುವುದಿಲ್ಲ ಹಾಗೂ\nಅದರಿಂದ ನಮಗೆ ನಂಬಿಕೆ ಬರುವುದಿಲ್ಲ. ನಾವು ಯಾವುದೇ ಕೆಲಸ ಮಾಡಿದರೂ ಅದನ್ನು ತಿಳಿದು-ನಂಬಿ\n\nಮಾಡಬೇಕು. ಅದಕ್ಕೋಸ್ಕರ ಪ್ರತೀ ಹೆಜ್ಜೆಯಲ್ಲೂ ಶಾಸ್ತ್ರೀಯ ಅನುಭಾವ ಮುಖ್ಯ. ನಾನು ಅಂದರೇನು, ಸ್ವಭಾವ\nಅಂದರೇನು, ನನ್ನ ಸ್ವಭಾವವನ್ನು ನಿಯಂತ್ರಿಸುವ ಆ ಶಕ್ತಿ ಯಾವುದು, ಕೈಹಿಡಿದು ನಡೆಸುವವ ಮತ್ತು ಫಲ\nಕೊಡುವವ ಯಾರು, ಇತ್ಯಾದಿ ವಿಚಾರ ತಿಳಿದಾಗ ಅಲ್ಲಿ ಅಹಂಕಾರಕ್ಕೆ ಎಡೆಯಿಲ್ಲ.\n\nಇಲ್ಲಿ ನಮಗೆ ಒಂದು ಪ್ರಶ್ನೆ ಬರಬಹುದು. ಭಗವಂತ ನಮಗೆ ಶಿಕ್ಷೆ ಏಕೆ ಕೊಡುತ್ತಾನೆ ಎಂದು. ದೇವರು ನಮಗೆ ಶಿಕ್ಷೆ\nಕೊಡುವುದು ದ್ವೇಷದಿಂದಲ್ಲ, ಅದರ ಹಿಂದಿರುವುದು ಅಪಾರ-ಅನಂತವಾದ ಕಾರುಣ್ಯ. ತಾಯಿ ಮಗುವಿಗೆ ಶಿಕ್ಷೆ\nಕೊಡುವ ಹಿಂದಿರುವ ಕಾರುಣ್ಯ ಹೇಗೋ ಹಾಗೆ. ಜೀವನದಲ್ಲಿ ಬರುವ ದುಃಖ ದುರಿತಗಳಿಂದ ಜೀವ\nಪಾಕವಾಗುತ್ತದೆ. ಜೀವನದಲ್ಲಿ ನಮಗೆ ಬರುವ ತಾಪತ್ರಯಗಳ ತಾಪಕ್ಕೆ ನಾವು ಬೇಯಬೇಕು, ಬೆಂದು\nಪಕ್ವವಾಗಬೇಕು. ಜೀವನದಲ್ಲಿ ಕಷ್ಟವನ್ನು ನೋಡದವನು ಎಂದೂ ಬೆಳೆಯುವುದಿಲ್ಲ. ಅವರಿಗೆ ಇನ್ನೊಬ್ಬರ ಸುಖ-\nದುಃಖ ಅರ್ಥವಾಗುವುದಿಲ್ಲ. ಜೀವ ಪಕ್ಚವಾಗುವುದೇ ಕಷ್ಟಗಳು ಬಂದಾಗ. ಇದು ಭಗವಂತ ನಮಗೆ ಕೊಡುವ\nಶಿಕ್ಷೆಯ ಹಿಂದಿರುವ ಕಾರುಣ್ಯ. ನಮ್ಮ ಪತನದ ಹಿಂದೆ ಒಂದು ಉದ್ಧಾರದ ಬೀಜವಿರುತ್ತದೆ. ದುಃಖದ ಹಿಂದೆ\nಸುಖದ ಬೀಜವಿರುತ್ತದೆ. ಹೀಗೆ ಶಾಸ್ತ್ರೀಯವಾಗಿ ನೋಡಿದಾಗ ಇಡೀ ಪ್ರಪಂಚದ ಹಿಂದೆ ಇರುವ ವಿಶ್ವಶಕ್ತಿ, ಮಹಾ\nಕಾರುಣ್ಯಮೂರ್ತಿಯಾಗಿ ನಮ್ಮನ್ನು ರಕ್ಷಿಸುತ್ತಿದೆ. ಎನ್ನುವ ಎಚ್ಚರ ಬರುತ್ತದೆ. ಏಳಲು ಬಲವಿಲ್ಲದ ಮಗುವನ್ನು\nತಾಯಿ ಹೇಗೆ ನೋಡಿಕೊಳ್ಳುತ್ತಾಳೇ, ಹಾಗೇ ಭಗವಂತ ನಮ್ಮನ್ನು ಪ್ರತೀಕ್ಷಣವೂ ರಕ್ಷಿಸುತ್ತಿದ್ದಾನೆ. ಇದು\nಅಧ್ಯಾತ್ಮ ಮಾರ್ಗದಲ್ಲಿ ನಿರಂತರ ಇರಬೇಕಾದ ಅಂತಃಪ್ರಜ್ಞೆ.",
  "5.17": "ತತ್‌ ಬುದ್ಧಯಃ ತತ್‌ ಆತ್ಮಾನಃ ತತ್‌ ನಿಷ್ಠಾಃ ತತ್‌ ಪರಾಯಣಾಃ |\n\nಗಚ್ಛಂತಿ ಅಪುನಃ ಆವೃತ್ತಿಮ್‌ ಜ್ಞಾನ ನಿರ್ಧೂತ ಕಲ್ಮಷಾಃ -ಅವನಲ್ಲೇ ಬಗೆ ನೆಟ್ಟ ವರು, ಅವನೇ ಸ್ವಾಮಿಯೆಂದು\nನಂಬಿದವರು, ಅವನಲ್ಲೇ ನೆಲೆಗೊಡವರು, ಅವನಿಗೇ ಶರಣಾದವರು, ಅವನನ್ನು ಕಂಡು ಬಾಳ ಕೊಳೆಯನ್ನು\nಕಳೆದುಕೊಂಡವರು ಮತ್ತೆ ಮರಳಿಬಾರದ ತಾಣಕ್ಕೆ ತೆರಳುತ್ತಾರೆ.\n\nಅಜ್ಞಾನವನ್ನು ಅಳಿಸುವ ಮಾರ್ಗವನ್ನು ಕೃಷ್ಣ ಇಲ್ಲಿ ಸೊಗಸಾಗಿ ವಿವರಿಸಿದ್ದಾನೆ. ಮೊದಲನೆಯದಾಗಿ\nಭಗವಂತನಲ್ಲೇ ಬುದ್ಧಿಯನ್ನಿಡುವುದು(ತತ್‌ ಬುದ್ಧಯಃ); ನಮ್ಮ ಮನಸ್ಸು ಎಲ್ಲಾ ವಿಷಯಗಳನ್ನು ಗ್ರಹಿಸುತ್ತದೆ,\nಬುದ್ಧಿ ತೀರ್ಮಾನ ಮಾಡುತ್ತದೆ. ನಾವು ಭಗವಂತನಲ್ಲಿ ಸ್ಥಿರವಾಗಿ ನಮ್ಮ ಬುದ್ಧಿಯನ್ನು ಇಟ್ಟರೆ ಆತ ನಮ್ಮ\nಬುದ್ಧಿಯಲ್ಲಿ ಬಂದು ಕೂರುತ್ತಾನೆ. ಇದಕ್ಕಾಗಿ ನಾವು ಭಗವಂತನ ಕುರಿತಾಗಿ ನಮ್ಮ ಅರಿವನ್ನು\nಬೆಳೆಸಿಕೊಳ್ಳಬೇಕು. ಭಗವಂತನ ವಿಷಯದ ನಿರಂತರ ಸಾಧನೆಯಿಂದ ನಾವು ಭಗವಂತನಲ್ಲಿ ನಮ್ಮ\nಬುದ್ಧಿಯನ್ನು ನೆಲೆಗೊಳಿಸಿದಾಗ, ಭಗವಂತ ನಮ್ಮ ಬುದ್ಧಿಯಲ್ಲಿ ನೆಲೆಗೊಳ್ಳುತ್ತಾನೆ.\n\nಭಗವಂತನಿಗೆ ನಿನ್ನ ಆತ್ಮವನ್ನು, ನಿನ್ನ ಮನಸ್ಸನ್ನು ಅರ್ಪಿಸು(ತತ್‌ ಆತ್ಮಾನಃ); ಅವನು ನಿನ್ನ ಸ್ವಾಮಿಯಾಗಲಿ,\nನೀನು 'ಭಗವಂತನೇ ಸದಾ ನನ್ನನ್ನು ಮಾರ್ಗದರ್ಶನ ಮಾಡುವ ಪ್ರಭು, ಅವನ ನಿಯಂತ್ರಣದಲ್ಲಿ ನನ್ನ ಬದುಕು\nಮಾಂಗಲಿಕವಾಗಿ ನಡೆಯಲಿ' ಎಂದು ನಿರಂತರ ಪ್ರಾರ್ಥನೆ ಮಾಡು.\n\nಭಗವಂತನಲ್ಲಿ ನಿಷ್ಠೆ(ತತ್‌ ನಿಷ್ಠಾಃ) ಇಲ್ಲದೇ ಇದ್ದರೆ ಏನನ್ನೂ ಮಾಡಲು ಸಾಧ್ಯವಿಲ್ಲ. ನಿಷ್ಠಾ ಅಂದರೆ ಭಕ್ತೆ.\nಆದ್ದರಿಂದ ಭಗವಂತನಲ್ಲಿ ಸದಾ ಭಕ್ತಿ ಇರಬೇಕು. ಭಕ್ತಿ ಇಲ್ಲದೆ ಧ್ಯಾನ, ಪೂಜೆ ಮಾಡುವುದರಿಂದ ಯಾವುದೇ\nಉಪಯೋಗವಿಲ್ಲ. ಒಮ್ಮೆ ನಮಗೆ ಭಗವಂತನ ಬಗ್ಗೆ ಜ್ಞಾನ ಬಂದರೆ ಭಕ್ತಿ ತನ್ನಷ್ಟಕ್ಕೆ ತಾನೇ ಬರುತ್ತದೆ.\nಜ್ಞಾನವಿಲ್ಲದ ಭಕ್ತಿ-ಮೂಡಭಕ್ತಿ. ಜ್ಞಾನವಿದ್ದು ಭಕ್ತಿ ಇಲ್ಲದಿದ್ದರ(ಅಹಂಕಾರದಿಂದ) ಆ ಜ್ಞಾನದಿಂದ ಯಾವ\nಉಪಯೋಗವೂ ಇಲ್ಲ, ಅದು ಶುಷ್ಕ ಪಾಂಡಿತ್ಯವೆನಿಸುತ್ತದೆ.\n\nಹೀಗೆ ಮನಸ್ಸು-ಬುದ್ಧಿಯನ್ನು ಭಗವಂತನಲ್ಲಿ ನೆಲೆಸಿ ಜ್ಞಾನಪೂರ್ವಕ ಭಕ್ತಿಯನ್ನು ರೂಢಿಸಿಕೊಂಡಾಗ, ಎಲ್ಲಕ್ಕಿಂತ\nದೊಡ್ಡ ಆಶ್ರಯ ಭಗವಂತ(ತತ್‌ ಪರಾಯಣಾಃ।) ಎನ್ನುವ ಅರಿವು ಬರುತ್ತದೆ. ಇದರಿಂದ ಸಂಸಾರವೇ ಸರ್ವಸ್ವ\nಎನ್ನುವ ಭ್ರಮೆ ಹೊರಟು ಹೋಗುತ್ತದೆ. ಪುರಂದರದಾಸರು ಹೇಳಿದಂತೆ: \"ಅಲ್ಲಿದೆ ನಮ್ಮನೆ, ಇಲ್ಲಿರುವುದು\nಸುಮ್ಮನೆ\". ಅಂದರೆ ಈ ಸಂಸಾರ ಶಾಶ್ವತ ಅಲ್ಲ ಹಾಗೂ ಯಾವಾಗ ಇಲ್ಲಿಂದ ಹೊರಡಬೇಕೋ ನಮಗೆ\nಗೊತ್ತಿಲ್ಲ. ಹಾಗಿರುವಾಗ 'ನನ್ನದು' ಎನ್ನುವ ಅಹಂಕಾರ ಏಕೆ? ಇದು ಪಲಾಯನವಾದವಲ್ಲ, ನಾವು ಯಾವುದನ್ನೂ\nಬಿಡಬೇಕಾಗಿಲ್ಲ, ಆದರೆ ಅದೇ ಸರ್ವಸ್ವ ಎನ್ನುವ ಭ್ರಮೆಯನ್ನು ಬಿಡುವುದು ಅಷ್ಟೇ. ಭಗವಂತ ಕೊಟ್ಟಿದ್ದಾನೆ,\nಕೊಟ್ಟಷ್ಟು ಕಾಲ ಇಟ್ಟಷ್ಟು ಕಾಲ ಇರುವುದು. ಅದೇ ರೀತಿ ಯಾವ ತತ್ತ್ವಾಭಿಮಾನಿ ದೇವತೆಗಳನ್ನೂ ನಾವು\nತಿರಸ್ಕರಿಸಬಾರದು. ಅವರು ನಮಗೆ ಭಗವಂತನನ್ನು ಸೇರುವ ಮಾರ್ಗ ತೋರಿಸುವ ಭಗವಂತನ ಪರಿವಾರ,\nಆದರೆ ಅವರೇ ಸರ್ವಸ್ವ ಅಲ್ಲ.\n\nಎಲ್ಲಕ್ಕಿಂತ ಮೇಲೆ ಎಲ್ಲರಿಗೂ ಆಶ್ರಯವಾಗಿರತಕ್ಕಂತಹ ಪರತತ್ವದ ಎಚ್ಚರದೊಂದಿಗೆ ನಿನ್ನ ಪಾಲಿಗೆ ಬಂದ\nಕರ್ತವ್ಯವನ್ನು ಭಗವಂತನ ಪ್ರಸಾದವೆಂದು ಮಾಡು. ಓಡಿಹೋಗಬೇಡ, ಸಂಸಾರದಲ್ಲಿ ಬದುಕು, ಭಗವಂತ ಏನು\nಕೊಟ್ಟ ಅದನ್ನು ಸ್ವೀಕರಿಸು. ನಿನ್ನೆಲ್ಲಾ ಸರ್ವಸ್ವವನ್ನು 'ಪರಮ ರಕ್ಷಕ ಭಗವಂತ' ಎಂದು ಅವನಲ್ಲಿ ಅರ್ಪಿಸು. ಹೀಗೆ\nಬದುಕುವುದರಿಂದ, ನಮ್ಮ ಆತ್ಮಕ್ಕೆ ಅಂಟಿದ ಕೊಳೆ ತೊಳೆದು ಹೋಗುತ್ತದೆ, ಮನಸ್ಸು ಸ್ವಚ್ಛವಾಗುತ್ತದೆ. ಆಗ\nಜ್ಞಾನ ಬೆಳಗುತ್ತದೆ-ಭಗವಂತನ ಸಾಕ್ಷಾತ್ಕಾರವಾಗುತ್ತದೆ. ಇದರಿಂದ ಮತ್ತೆ ಮರಳಿ ಬಾರದ ಶಾಶ್ವತ\nಮೋಕ್ಷವನ್ನು ಜೀವ ಪಡೆಯಬಲ್ಲ.\n",
  "5.18": "ವಿದ್ಯಾ ವಿನಯ ಸಂಪನ್ನೇ ಬ್ರಾಹ್ಮಣೇ ಗವಿ ಹಸ್ತಿನಿ ।\n\nಶುನಿ ಚ ಏವ ಶ್ವಪಾಕೇ ಚ ಪಂಡಿತಾಃ ಸಮದರ್ಶಿನಃ -ನಿಜವಾದ ಪಂಡಿತ-ವಿದ್ಯಾವಿನಯಸಂಪನ್ನ,\nಬ್ರಾಹ್ಮಣವರ್ಣ, ಆಕಳು, ಆನೆ, ನಾಯಿ, ಹೊಲಗೇಡಿ ಹೀನ ಮಾನವನಲ್ಲಿ ಕೂಡಾ ಏಕರೂಪನಾದ\nಭಗವಂತನನ್ನು ಕಾಣಬಲ್ಲ.\n\nಈ ಶ್ಲೋಕ ಬಹಳ ಮಂದಿಗೆ ಅರ್ಥವಾಗುವುದಿಲ್ಲ ಅಥವಾ ಅರ್ಥವಾಗದೇ ಅಪಾರ್ಥ ಮಾಡಿಕೊಳ್ಳುವವರೇ ಹೆಚ್ಚು.\nಒಬ್ಬ ಸಾಧಕನ ಉಪಾಸನೆಯಲ್ಲಿ ಇರಬೇಕಾದ ಇನ್ನೊಂದು ಮುಖವನ್ನು ಕೃಷ್ಣ ಇಲ್ಲಿ ವಿವರಿಸಿದ್ದಾನೆ. ಇದು\n\nತುಂಬಾ ಒಳ ನೋಟವನ್ನು ಅಪೇಕ್ಷಿಸುವ ಶ್ಲೋಕ. ಇಲ್ಲಿ ಮೂರು ತರಹದ ಮನುಷ್ಯನ ಸ್ಥಿತಿಯನ್ನು ಮತ್ತು ಮೂರು\nತರಹದ ಪ್ರಾಣಿಗಳ ಸ್ಥಿತಿಯನ್ನು ಕೃಷ್ಣ ವಿವರಿಸಿದ್ದಾನೆ. ಮಾನವರಲ್ಲಿ: ವಿದ್ಯಾವಿನಯಸಂಪನ್ನ, ಬ್ರಾಹ್ಮಣ ಮತ್ತು\nಶ್ವಪಾಕ. ಪ್ರಾಣಿಗಳಲ್ಲಿ: ಗೋವು, ಆನೆ ಮತ್ತು ನಾಯಿ.\n\nಮನುಷ್ಯರಲ್ಲಿ ಜ್ಞಾನದ ತುತ್ತ ತುದಿಯನ್ನು ತಲುಪಿದವ ಮತ್ತು ಅತ್ಯಂತ ಶ್ರೇಷ್ಠ 'ವಿದ್ಯಾ ವಿನಯಸಂಪನ್ನ'. ವೇದದ\nಕೆಲವು ಭಾಗವನ್ನು ಪ್ರಾಮಾಣಿಕವಾಗಿ ಮನನ ಮಾಡಿ ಉಪಾಸನೆ ಮಾಡುವವ ಬ್ರಾಹ್ಮಣ. (ಇಲ್ಲಿ ಹೇಳುವ\nಬ್ರಾಹ್ಮಣ-ಬ್ರಾಹ್ಮಣವರ್ಣ; ಜಾತಿ ಅಲ್ಲ. ಈ ಬಗ್ಗೆ ವಿಶೇಷವಾಗಿ ಹಿಂದಿನ ಅಧ್ಯಾಯದಲ್ಲಿ ವಿಶ್ನೇಶಿಸಿದ್ದೇವೆ). ಸಮಸ್ತ\nವೇದವನ್ನು ಓದಿ ಆ ವೇದೋಕ್ತವಾದ ವಿಧಾನವನ್ನು ಜೀವನದಲ್ಲಿ ಅಳವಡಿಸಿಕೊಂಡವ ವೇದಜ್ಞ. ವೇದದ\nಅಂತರಂಗದ ಅರ್ಥವನ್ನು ತಿಳಿದವ 'ವೇದ ಅರ್ಥಜ್ಞ'-ಆತನೇ “ವಿದ್ಯಾ ವಿನಯಸಂಪನ್ನ'\n\nಮಾನವರಲ್ಲಿ ಅತೀ ಕೀಳು ಅಂದರೆ ಶ್ವಪಾಕ. ಶ್ವಪಾಕ ಎಂದರೆ ನಾಯಿಯ ಮಾಂಸ ತಿನ್ನುವವ ಎಂದರ್ಥ.\nಅಂದರೆ ಆತನಿಗೆ ಯಾವ ಸಂಸ್ಕಾರವೂ ಇಲ್ಲ, ಹೊಟ್ಟೆಗಾಗಿ ಏನನ್ನಾದರೂ ತಿನ್ನುವವ. ಇದು ಮನುಷ್ಯನ\nಅಧಃಪತನದ ಪರಾಕಾಷ್ಠೆಯನ್ನು ಹೇಳುವಂತಾದ್ದು. ಹೀಗೆ ಅತ್ಯಂತ ಎತ್ತರಕ್ಕೇರಿದ ವಿದ್ಯಾವಿನಯಸಂಪನ್ನ,\nಅದರಿಂದ ಕೆಳಗೆ ಬ್ರಾಹ್ಮಣವರ್ಣ, ಅತ್ಯಂತ ಕೆಳಗೆ ಶ್ವಪಾಕ.\n\nಪ್ರಾಣಿಗಳಲ್ಲಿ ಗವ(ಗೋವು) ಅತ್ಯಂತ ಶ್ರೇಷ್ಠ ಪ್ರಾಣಿ. ಅದರ ನಂತರ ಮಧ್ಯಮ ಹಸ್ತಿನಿ(ಆನೆ), ಕೊನೆಗೆ ನಾಯಿ.\nಪ್ರಾಚೀನರು ಮನಸ್ಸನ್ನು ಯಾವುದು ಶುದ್ಧಗೊಳಿಸುತ್ತದೇ, ಅದನ್ನು 'ಶುದ್ಧ' ಎಂದು ತೀರ್ಮಾನ ಮಾಡಿದರು.\nಉದಾಹರಣೆಗೆ ಜಿಂಕೆ ಮತ್ತು ಹುಲಿ ಚರ್ಮ ಮನಸ್ಸನ್ನು ಏಕಾಗ್ರ ಮಾಡಲು ಸಹಕರಿಸುತ್ತದೆ.ಭೂಮಿಯಲ್ಲಿನ ಕೆಟ್ಟ\nಕಂಪನ ಧ್ಯಾನದ ಕಾಲದಲ್ಲಿ ನಮ್ಮ ದೇಹವನ್ನು ಪ್ರವೇಶಿಸದಂತೆ ತಡೆಯಲು ಈ ಚರ್ಮವನ್ನು\nಉಪಯೋಗಿಸುತ್ತಾರೆ. ಆದ್ದರಿಂದ ಅದು ಶುದ್ಧ ಮತ್ತು ಶ್ರೇಷ್ಠ... ಅದೇ ರೀತಿ ಗೋವು; ಈ ಪ್ರಾಣಿಯಲ್ಲಿ\nಯಾವಾಗಲೂ ಸಾತ್ವಿಕವಾದ ಸ್ಪಂದನವಿರುತ್ತದೆ. ಹಸುವಿನಲ್ಲಿರುವ ಇನ್ನೊಂದು ಶ್ರೇಷ್ಠ ಅಂಶ\nಎಂದರೆ: ಈ ಪ್ರಪಂಚದಲ್ಲಿ ಎಲ್ಲಾ ಪ್ರಾಣಿಗಳ ಮಲ-ಮೂತ್ರ ವರ್ಜ್ಯ. ಆದರೆ ಹಸುವಿನ ಮಲ ಮೂತ್ರ ಶ್ರೇಷ್ಠ. ಹೀಗೆ\nಪ್ರಾಣಿಗಳಲ್ಲಿ ಹಸು ಅತ್ಯಂತ ಶ್ರೇಷ್ಠ. ಗೃಹಪ್ರವೇಶ ಕಾಲದಲ್ಲಿ ಹಸುವನ್ನು ಮೊದಲು ಮನೆಯೊಳಗೆ ತರುವುದಕ್ಕೆ\nಇದೇ ಕಾರಣ.\n\nಪ್ರಾಚೀನರು ನಾಯಿಯನ್ನು ಅತ್ಯಂತ ಕೆಳವರ್ಗ ಎಂದು ಪರಿಗಣಿಸಿದರು. ನಮಗೆ ತಿಳಿದಂತೆ ನಾಯಿ ತನ್ನ\nಯಜಮಾನನಿಗಾಗಿ ತನ್ನ ಪ್ರಾಣವನ್ನೇ ಕೊಡಲು ಸಿದ್ಧವಿರುವ ಸಾಕು ಪ್ರಾಣಿ. ಆದರೆ ಇದು ಅತಿ ಹೆಚ್ಚು ತಾಮಸಿಕ\nಸ್ಪಂದನವಿರುವ ಪ್ರಾಣಿ. ಆದ್ದರಿಂದ ನಾಯಿಯಿಂದ ನಮ್ಮ ಮಾನಸಿಕ ಅಭಿವೃದ್ಧಿಗೆ ಏನೂ ಪೋಷಣೆ\nಇಲ್ಲ. ಈ ಕಾರಣದಿಂದ ನಾಯಿಯನ್ನು ಪ್ರಾಚೀನರು ಅತ್ಯಂತ ಕನಿಷ್ಠ ಸ್ಥಾನದಲ್ಲಿರಿಸಿದರು. ನಾಯಿಯನ್ನು ಎಂದೂ\nಮನೆಯೊಳಗೆ ಸೇರಿಸದಿರಲು ಇದು ಕಾರಣ. ಹೀಗೆ ಪ್ರಾಣಿಗಳಲ್ಲಿ ಹಸು ಶ್ರೇಷ್ಠ, ಆನೆ ಮಧ್ಯಮ ಮತ್ತು ನಾಯಿ\nಕನಿಷ್ಠ.\n\nಇಲ್ಲಿ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಪಂಡಿತಾಃ ಸಮದರ್ಶಿನಃ” ಎಂದು. ಅಂದರೆ. ಪಂಡಿತರು ಸಮದೃಷ್ಟಿ\nಉಳ್ಳವರಾಗಿರುತ್ತಾರೆ ಎಂದರ್ಥ. ಅವರು. ಪ್ರತಿಯೊಂದರಲ್ಲೂ, ಅದರೊಳಗಿರುವ ಭಗವಂತನ ವಿಶೇಷ\nಅಭಿವ್ಯಕ್ತವನ್ನು ಕಾಣುತ್ತಾರೆ. ಹಸುವಾಗಿರಲಿ, ನಾಯಿಯಾಗಿರಲಿ, ವಿದ್ಯಾವಿನಯಸಂಪನ್ನರಾಗಿರಲಿ ಏನೇ ಇರಲಿ.\nಏಕೆಂದರೆ ಭಗವಂತ ಸರ್ವಾಂತರ್ಯಮಿ, ಆತ ಎಲ್ಲರ ಒಳಗೂ ಇದ್ದಾನೆ. ಆತನ ಅಭಿವ್ಯಕ್ತಿ ಮಾತ್ರ ಬೇರೆ ಬೇರೆ.\n\nಆತ ಒಂದೊಂದು ಜೀವಿಯಲ್ಲೂ ಒಂದೊಂದು ಅನನ್ಯ ಅಸಾಧಾರಣ ಗುಣಧರ್ಮದಿಂದ\nಅಭಿವ್ಯಕ್ತನಾಗುತ್ತಾನೆ. ಉದಾಹರಣೆಗೆ: ಮುಟ್ಟಿದರೆ ಮುನಿ ಗಿಡ (Touch-me-not) ಯಾರಿಗೂ ಬೇಡವಾಗಿ\nಬೆಳೆಯುವ ಈ ಗಿಡದಲ್ಲಿ ಅಮೋಘವಾದ ಔಷಧೀಯ ಗುಣವಿದೆ. ಈ ಗಿಡವನ್ನು (ಹೂ ರಹಿತ) ಜಜ್ಜಿ ಬಟ್ಟೆಯಲ್ಲಿ ಕಟ್ಟಿ\nಗಂಜಿಯ ಜೊತೆಗೆ ಬೇಯಿಸಿ, ಆ ಗಂಜಿಯನ್ನು ಸೇವಿಸಿದರೆ ಅಥವಾ ಈ ಗಿಡದ ಕಷಾಯಮಾಡಿ ಕುಡಿದರೆ,\nಯಾವುದೇ ಶಸ್ತ್ರಚಿಕಿತ್ಸೆ ಇಲ್ಲದೇ ಮೂಲವ್ಯಾಧಿ ಗುಣಮುಖವಾಗುತ್ತದೆ. ಅದೇ ರೀತಿ ಜೇನುನೊಣ:\nಹೂವಿಂದ ರಸವನ್ನು ಹೀರಿ ಜೇನನ್ನು ತಯಾರಿಸುವ ಅಸಾಧಾರಣ ಶಕ್ತಿ ಇರುವುದು ಈ ಪುಟ್ಟ ಹುಳದಲ್ಲಿ. ನಮ್ಮ\nತಾಂತ್ರಿಕತೆಯಿಂದ ಕೃತಕವಾಗಿ ಜೇನನ್ನು ತಯಾರಿಸಲು ಬರುವುದಿಲ್ಲ.\n\nಈ ಪ್ರಪಂಚದಲ್ಲಿ ಏನೇನು ಹುಟ್ಟುತ್ತದೋ ಅದರೊಳಗೆ ವಿಶಿಷ್ಟ ಶಕ್ತಿಯಾಗಿ ತುಂಬಿರುವ, ನಿಯಾಮಕ ಶಕ್ತಿಯಾದ\nಜನೇಶ್ವರ ಭಗವಂತನನ್ನು ಅಪರೋಕ್ಷ ಜ್ಞಾನಿಗಳು ಪ್ರತ್ರಿಯೊಂದರಲ್ಲೂ ಕಾಣುತ್ತಾರೆ. ನಾಯಿ ಇರಲಿ, ಹಸು\nಇರಲಿ, ಶ್ವಪಾಕನಿರಲಿ, ವಿದ್ಯಾವಿನಯಸಂಪನ್ನನಿರಲಿ. ಪಂಡಿತ-ಎಲ್ಲವುದರಲ್ಲೂ ಆ ಭಗವಂತನ ಮಹಿಮೆಯನ್ನೇ\nಕಾಣುತ್ತಾನೆ.\n\nತಾನು ಎಲ್ಲವುದರಲ್ಲೂ ಅಂತರ್ಯಾಮಿಯಾಗಿ ಅತ್ಯಂತ ಶುದ್ಧನಾಗಿ ತುಂಬಿದ್ದು, ನಿರ್ಲಿಪ್ತನಾಗಿ, ಒಂದೊಂದು\nವಸ್ತುವಿಗೆ ಒಂದೊಂದು ರೀತಿಯ ವಿಶಿಷ್ಟ ಶಕ್ತಿಯನ್ನು ಕೊಡುವ ಭಗವಂತ, ಈ ಅನಂತ ಪ್ರಪಂಚವನ್ನು ಸೃಷ್ಟಿ\nಮಾಡಿ ನಮ್ಮ ಕಣ್ಣ ಮುಂದೆ ಇಟ್ಟ. ಇಂತಹ ಭಗವಂತನ ಮಹಿಮೆಯನ್ನು ಪ್ರತಿಯೊಂದು ವಸ್ತುವಿನಲ್ಲೂ ನೋಡಿ\nಅನುಸಂಧಾನ ಮಾಡಬೇಕು. ಆತ ಎಲ್ಲಾ ಕಡೆಯೂ ಜ್ಞಾನಾನಂದಪೂರ್ಣನಾಗಿ, ಸರ್ವಗುಣಪೂರ್ಣ-\nಸರ್ವಗತನಾಗಿ, ಪ್ರತಿಯೊಂದು ಅಣು-ಕಣದೊಳಗೆ ತುಂಬಿದ್ದಾನೆ ಎನ್ನುವ ಅನುಸಂಧಾನ -ಅಪರೋಕ್ಷ ಜ್ಞಾನಕ್ಕೆ\nಬೇಕಾದ ಸಮದರ್ಶನ.\n",
  "5.19": "ಇಹ ಏವ ತೈಃ ಜಿತಃ ಸರ್ಗಃ ಯೇಷಾಮ್‌ ಸಾಮ್ಯೇ ಸ್ಥಿತಮ್‌ ಮನಃ ।\n\nನಿರ್ದೋಷಮ್‌ ಹಿ ಸಮಮ್‌ ಬ್ರಹ್ಮ ತಸ್ಮಾತ್‌ ಬ್ರಹ್ಮಣಿ ತೇ ಸ್ಥಿತಾಃ -ಭಗವಂತನ ಏಕ ರೂಪತೆಯಲ್ಲಿ ಬಗೆ\nನೆಟ್ಟವರು ಇಲ್ಲಿದ್ದೇ ಈ ಬಾಳನ್ನು ಗೆದ್ದವರು. ಭಗವಂತ ಎಲ್ಲೆಡೆಯೂ ದೋಷದ ನಂಟಿರದ ಏಕರೂಪಿ. ಆದ್ದರಿಂದ\nಹೀಗೆ ತಿಳಿದವರು ಭಗವಂತನಲ್ಲಿ ನೆಲೆಗೊಂಡವರು.\n\nಎಲ್ಲಾ ಕಡೆ ಇರುವ ಸರ್ವಗುಣಪೂರ್ಣ ಭಗವಂತ ಎಲ್ಲಾ ವಸ್ತುವಿನಲ್ಲಿಯೂ ತುಂಬಿದ್ದಾನೆ. ಎನ್ನುವ\nಅನುಸಂಧಾನದಲ್ಲಿ ನಮ್ಮ ಮನಸ್ಸು ನೆಟ್ಟಾಗ ಹುಟ್ಟು ಸಾವಿನ ಆಚೆಗಿನ ಮೋಕ್ಷದ ಬಾಗಿಲು ನಮಗೆ ತೆರೆದಂತೆ.\nಭಗವಂತ ಯಾವ ವಸ್ತುವಿನಲ್ಲಿದ್ದರೂ ಅವನಿಗೆ ದೋಷವಿಲ್ಲ, ಆತ ಎಲ್ಲಾ ಕಡೆ ನಿರ್ದುಷ್ಟನಾಗಿದ್ದಾನೆ. ಯಾವ\nಅಧಿಷ್ಠಾನದಲ್ಲಿದ್ದರೂ ಕೂಡಾ ಆತ ನಿರ್ಲಿಪ್ತನಾಗಿ. ಅಲ್ಲಿ ತುಂಬಿದ್ದಾನೆ. ಇದನ್ನು ತಿಳಿದವರ ಮನಸ್ಸು\n\nಭಗವಂತನಲ್ಲಿ ನೆಲೆ ನಿಂತಿರುತ್ತದೆ. ಆದ್ದರಿಂದ ಅವರು ಮರಳಿ ಬಂಧನಕ್ಕೊಳಗಾಗದೇ ಶಾಶ್ವತ ಮೋಕ್ಷವನ್ನು\nಪಡೆಯುತ್ತಾರೆ.\n\nಹಿಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ಕೃಷ್ಣ ಆಧ್ಯಾತ್ಮಿಕವಾಗಿ ಭಗವಂತನ ರೂಪದ ಸಮದೃಷ್ಟಿ ಬಗ್ಗೆ ವಿವರಿಸಿದ. ಮುಂದಿನ\nಶ್ಲೋಕದಲ್ಲಿ ಅದಕ್ಕೆ ಪೂರಕವಾಗಿ ಸಾಮಾಜಿಕವಾಗಿ ನಮ್ಮ ಬದುಕಿನಲ್ಲಿ ಹೇಗೆ ಸಮದೃಷ್ಟಿ ಬೆಳೆಸಿಕೊಳ್ಳಬೇಕು\nಎನ್ನುವುದನ್ನು ವಿವರಿಸುತ್ತಾನೆ.\n",
  "5.20": "ನ ಪ್ರಹೃಷ್ಯೇತ್‌ ಪ್ರಿಯಮ್‌ ಪ್ರಾಪ್ಯ ನ ಉದ್ವಿಜೇತ್‌ ಪ್ರಾಪ್ಯ ಚ ಅಪ್ರಿಯಮ್‌ |\n\nಸಿರ ಬುದಿಃ ಅಸಮ್ಮೂಢಃ ಬ್ರಹ್ಮವಿತ್‌ ಬ್ರಹ್ಮಣಿ ಸಿತಃ -ಸುಖ ಬಂದಾಗ ಹಿಗಬಾರದು; ದುಃಖ ಬಂದಾಗ\nಛಿ ಧಿ ಛಿ ಣಿ\n\nಕುಗ್ಗಬಾರದು.. ಇಂಥವನು ಬಗೆಗಟ್ಟಿಗೊಂಡವನು. ಎಚ್ಚರ ತಪ್ಪದವನು. ಭಗವಂತನನ್ನರಿತವನು.\nಭಗವಂತನಲ್ಲೇ ನೆಲೆ ನಿಂತವನು.\n\nನಮ್ಮ ಜೀವನ ಎನ್ನು ವುದು ಸುಖ-ದುಃಖದ ಚಕ್ರಭ್ರಮಣ. ಯಾರಿಗೂ ಕೇವಲ ಸುಖ ಎಂದಾಗಲೀ, ಕೇವಲ ದುಃಖ\nಎಂದಾಗಲೀ ಇಲ್ಲ. ಎಂತಹ ಸಂಪತ್ತಿನ ಸುಪ್ಪತ್ತಿಗೆಯಲ್ಲಿದ್ದರೂ ಜೀವನದಲ್ಲಿ ಕಷ್ಟದ ಕ್ಷಣಗಳು ಇದ್ದೇ ಇರುತ್ತವೆ.\nಅದೇ ರೀತಿ ಕಷ್ಟ ದಲ್ಲಿರುವವನಿಗೂ ಸುಖದ ಕ್ಷಣಗಳು ಇದ್ದೇ ಇದೆ. ಬದುಕು ಎನ್ನು ವುದು ಸುಖ ದುಃಖಗಳ ಪ್ರವಾಹ.\nಈ ಶ್ಲೋಕದಲ್ಲಿ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ನಮಗೆ ಸುಖ-ದುಃಖವೆಂಬ ದ್ವಂದ್ವದಲ್ಲಿ ಸಮದೃಷ್ಟಿ ಇರಬೇಕು” ಎಂದು.\nಸಾಮಾನ್ಯವಾಗಿ ನಮಗೆ ಇಷ್ಟವಾದದ್ದು ಫಲಿಸಿದಾಗ ನಾವು ಹಿಗ್ಗುತ್ತೇವೆ. ನಮಗೆ ಅಪ್ರಿಯವಾದದ್ದು, ನಾವು\nಬಯಸದಂತಹ ಘಟನೆಗಳು ಸಂಭವಿಸಿದಾಗ ಉದ್ವೇಗಕ್ಕೊಳಗಾಗಿ ಕುಸಿದುಬಿಡುತ್ತೇವೆ, ತಳಮಳಿಸುತ್ತೇವೆ.\nಇದು ಸಹಜವಾಗಿ ನಮ್ಮ ಬದುಕಿನಲ್ಲಿ ನಾವು ನೋಡತಕ್ಕಂತಹ ಸ್ಥಿತಿ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಇವೆರಡೂ ಆಗದಂತೆ\nಮನಸ್ಸನ್ನು ಸ್ಥಿಮಿತದಲ್ಲಿಟ್ಟುಕೊಳ್ಳಬೇಕು” ಎಂದು. ಯಾವುದು ಅನಿವಾರ್ಯವೋ ಅದನ್ನು ಸಹಜವಾಗಿ\nಸ್ವೀಕರಿಸಬೇಕು. ಅದನ್ನು ಬಿಟ್ಟು “ಹೀಗಾಗಬಾರದು, ಹಾಗಾಗಬಾರದು' ಎಂದು ಕುಳಿತರೆ ಮನಸ್ಸು\nಗೊಂದಲಕ್ಕೊಳಗಾಗುತ್ತದೆ. ಇದು ಮನಃಶಾಸ್ತ್ರ. ಇದರ ಅರ್ಥ ಸುಖ ಬಂದಾಗ ಅದನ್ನು ಅನುಭವಿಸಬಾರದು\nಎಂದಲ್ಲ. ಯಾವುದು ಬಂತೋ ಅದನ್ನು ಹಾಗೇ ಸ್ವೀಕರಿಸು, ಆದರೆ ಅತಿಯಾದ ಹಾರಾಟ ಬೇಡ. ಬದುಕಿನಲ್ಲಿ\nಎಲ್ಲವೂ ಬರುತ್ತದೆ ಹೋಗುತ್ತದೆ, ಯಾವುದೂ ಶಾಶ್ವತವಲ್ಲ ಎನ್ನುವ ಮನೋವೃತ್ತಿ ಬೆಳೆಸಿಕೊಳ್ಳಬೇಕು.\nಯಾವುದೋ ಒಂದನ್ನು ಅತಿಯಾಗಿ ಹಚ್ಚಿಕೊಂಡರೆ ಒಂದು ವೇಳೆ ಅದು ನಮ್ಮಿಂದ ದೂರವಾದರೆ\nತಡೆದುಕೊಳ್ಳಲಾಗುವುದಿಲ್ಲ. ಇದರಿಂದ ನಾವು ಮಾನಸಿಕವಾಗಿ ವ್ಯಾಕುಲತೆಗೊಳಗಾಗುತ್ತೇವೆ. ಅದರಿಂದ ಚಿಕ್ಕ\nಚಿಕ್ಕ ವಿಷಯಕ್ಕೆ ಆತ್ಮಹತ್ಯೆಯಂತಹ ಘೋರ ಪಾಪವನ್ನು ಮಾಡಲು ನಮ್ಮ ಮನಸ್ಸು ಮುಂದಾಗುತ್ತದೆ.\nಆದ್ದರಿಂದ ಬದುಕಿನ ಯಶಸ್ವೀ ಸೂತ್ರ ಎಂದರೆ ಯಾವುದಕ್ಕೂ ತಲೆಕೆಡಿಸಿಕೊಳ್ಳದೇ ಬಂದದ್ದನ್ನು ಬಂದಂತೆ\n\nಅನುಭವಿಸುವುದು. ನಾವು ಬಯಸಿದಂತೆ ಪ್ರಪಂಚವಿಲ್ಲ-ಪ್ರಪಂಚವಿದ್ದಂತೆ ನಾವು. ಅದನ್ನು ಸ್ವಾಗತಿಸಿ ಯಾವ\nಉದ್ವೇಗವೂ ಇಲ್ಲದೆ ಬದುಕುವುದನ್ನು ಕಲಿತಾಗ ಮನಸ್ಸು ಗಟ್ಟಿಯಾಗುತ್ತದೆ.\n\nಣ\n\nಆಧ್ಯಾತ್ಮಿಕವಾಗಿ ನೋಡಿದಾಗ ನಮಗೆ ಪ್ರಿಯವಾದದ್ದು-ಅಪ್ರಿಯವಾದದ್ದು ಎಂದು ಸಾವು ಯಾವುದಕ್ಕೆ\nಹೇಳುತ್ತೇವೋ, ಅದು ನಿಜವಾಗಿಯೂ ಒಳ್ಳೆಯದು]ಕೆಟ್ಟದ್ದು ಎಂದು ಹೇಳಲು ಬರುವುದಿಲ್ಲ. ಇಷ್ಟವಾದದ್ದು\nಒಳ್ಳೆಯದಾಗಿರಬೇಕಾಗಿಲ್ಲ. ಕೆಲವೊಮ್ಮೆ ನಮಗೆ ಅಪ್ರಿಯವಾದದ್ದು ನಮಗೆ ಹಿತವನ್ನು ಕೊಡುತ್ತದೆ. ಆದರೆ ಅದು\nನಮಗೆ ತಿಳಿಯುವುದು ಮಾತ್ರ ತಡವಾಗಿ. ನಮ್ಮ ಜೀವನದಲ್ಲಿ ಬರುವ ಪ್ರತಿಯೊಂದು ಘಟನೆ ನಮ್ಮ ಮುಂದಿನ\nಬೆಳವಣಿಗೆಗೆ ಪೂರಕವಾಗಿರುತ್ತದೆ. ಒಬ್ಬ ಮನುಷ್ಯ ಅಧಃಪಾತ ಹೊಂದುವ ಪ್ರಾರಾಬ್ಧಕರ್ಮ ಹೊಂದಿದ್ದರೆ\nಆತನಿಗೆ ಬೇಕಾದಷ್ಟು ಸುಖ ಬರಬಹುದು! ಅವನು ಆ ಸುಖದಲ್ಲಿ ಮೈಮರೆತು ಮಾಡಬಾರದ್ದನ್ನು ಮಾಡಿ\nಅಧಃಪಾತ ಹೊಂದಬಹುದು; ಕಷ್ಟದಲ್ಲಿ ಜೀವ ಪಕ್ಚ್ವವಾಗಬಹುದು. ಕಠೋಪನಿಷತ್ತಿನಲ್ಲಿ ಈ ವಿಚಾರವನ್ನು\nವ್ಯಂಗ್ಯವಾಗಿ ಹೀಗೆ ಹೇಳಿದ್ದಾರೆ: “ಪ್ರೇಯೋ ಮಂದೋ ಯೋಗಕ್ಷೇಮಾದ್ವೃಣೀತೇ” (1-2-2). “ಹಿತವಾದದ್ದು\nಮತ್ತು ಇಷ್ಟವಾದದ್ದು ಎರಡೂ ಮುಂದೆ ಬಂದಾಗ ಯಾರು ಇಷ್ಟವಾದದ್ದನ್ನು ಆಯ್ಕೆ ಮಾಡುತ್ತಾರೆ-ಅವರು\nತಿಳಿಗೇಡಿಗಳು” ಎಂದು.\n\nನಮಗೆ ಇಷ್ಟವಾದದ್ದು ಹಿತವಾಗಿರಬೇಕೆಂದಿಲ್ಲ, ಅದಕ್ಕಾಗಿ ಹಾರಾಡುವುದು ಅರ್ಥಶೂನ್ಯ. ಅದೇ ರೀತಿ\nಜೀವನದಲ್ಲಿ ಯಾವುದೋ ಒಂದು ಅನಿಷ್ಠ ಘಟನೆ ನೆಡೆದಾಗ ಅದಕ್ಕಾಗಿ ಎಂದೂ ಗೊಂದಲಕ್ಕೊಳಗಾಗಬೇಕಿಲ್ಲ.\nಅದರಿಂದಲೇ ಮುಂದೆ ನಮಗೆ ಹಿತವಾಗಬಹುದು. ಈ ವಿಚಾರ ಹೆಚ್ಚಿನವರಿಗೆ ಅನುಭವಕ್ಕೆ ಬಂದಿರುತ್ತದೆ.\n\"ಹೀಗೇಕೆ ? ಹೀಗಾಗಬಾರದಿತ್ತು' ಎಂದು ಯೋಚಿಸುತ್ತಿರುತ್ತೇವೆ ಆದರೆ ಮುಂದೆ ಹಾಗೆ ಆದುದರಿಂದಲೇ ನಮ್ಮ\nಸಮಸ್ಯೆಗೊಂದು ದಾರಿ ಕಾಣುತ್ತದೆ. ಆದರೆ ಅದು ತಿಳಿಯುವುದು ಮಾತ್ರ ತಡವಾಗಿ. ಈ ಎಲ್ಲಾ ಕಾರಣದಿಂದ\nಸುಖಬಂದಾಗ ಸುಖದ ಭ್ರಮೆ ಬೇಡ, ದುಃಖ ಬಂದಾಗ ವ್ಯಾಕುಲತೆ ಬೇಡ. ಎರಡರ ಬಗ್ಗೆಯೂ ಸಮದೃಷ್ಟಿ ಇರಲಿ.\nಭಗವಂತ ಕೊಟ್ಟದ್ದನ್ನು ಪ್ರಾಮಾಣಿಕವಾಗಿ ಅನುಭವಿಸುತ್ತೇನೆ ಎನ್ನುವ ಅನುಸಂಧಾನವಿರಲಿ. ಮಾನಸಿಕ\nಗೊಂದಲ ಬೇಡ. ಬದುಕಿನಲ್ಲಿ ಯಾವುದು ಹಿತ-ಯಾವುದು ಅಹಿತ ಎನ್ನುವುದು ಭಗವಂತನಿಗೆ ಗೊತ್ತಿದೆ ಎನ್ನುವ\nಎಚ್ಚರ ಉಳ್ಳವನು ತನ್ನ ಮನಸ್ಸನ್ನು ಸುಖ-ದುಃಖದಲ್ಲಿ ನೆಟ್ಟಿರುವುದಿಲ್ಲ. ಬದಲಾಗಿ ಅವನ ಮನಸ್ಸು\nಭಗವಂತನಲ್ಲಿ ನೆಟ್ಟಿರುತ್ತದೆ. ಭಗವಂತ ನಮ್ಮನ್ನು ತಾಯಿ. ಮಗುವನ್ನು ನೋಡಿಕೊಂಡಂತೆ\nನೋಡಿಕೊಳ್ಳುತ್ತಾನೆ. ತಾಯಿಯಿಂದ ಬರುವ ಎಲ್ಲಾ ವಿಚಾರ ಮಗುವಿಗೆ ಇಷ್ಟವಾಗುವುದಿಲ್ಲ. ಆದರೆ ತಾಯಿ\nಮಗುವಿನ ಉದ್ಧಾರಕ್ಕೋಸ್ಕರ ಮಗುವಿನಲ್ಲಿ ಆ ಕೆಲಸವನ್ನು ಮಾಡಿಸುತ್ತಾಳೆ. ಅಲ್ಲಿ ಇಷ್ಟ ಮುಖ್ಯವಲ್ಲ, ಯಾವುದು\nಹಿತ ಅದು ಮುಖ್ಯ.",
  "5.21": "ಬಾಹ್ಯಸ್ಟರ್ಶೇಷು ಅಸಕ್ತ ಆತ್ಮಾ ವಿಂದತಿ ಆತ್ಮನಿ ಯತ್‌ ಸುಖಮ್‌ |\n\nಸಃ ಬ್ರಹ್ಮಯೋಗ ಯುಕ್ತ ಆತ್ಮಾ ಸುಖಮ್‌ ಅಕ್ಷಯಮ್‌ ಅಶ್ನುತೇ- ಹೊರಗಣ ಭೋಗಗಳಲ್ಲಿ ನಂಟು ಇರದವನು\nಬಗೆಯೊಳಗೆ [ಭಗವಂತನನ್ನು ನೆನೆದಾಗೊಮ್ಮೆ] ಎಂತಹ ಸುಖವನ್ನು ಪಡೆಯುತ್ತಾನೋ ಅದೇ ಸುಖವನ್ನು ಸದಾ\nಭಗವಂತನಲ್ಲಿ ಬಗೆನೆಟ್ಟ ಸಾಧಕ ನಿರಂತರ ಸವಿಯುತ್ತಾನೆ.\n\nಪ್ರಪಂಚದಲ್ಲಿ ಸುಖಕ್ಕೆ ಇರುವ ಸಾಧನ ಐದು. ರೂಪ, ರಸ, ಗಂಧ, ಸ್ಪರ್ಶ, ಶಬ್ದ. ಇದರ ಮುಖೇನ\nಅನುಭವಿಸುವುದು ತಪ್ಪಲ್ಲ. ಬೇಕು ಅನ್ನುವ ವಸ್ತುವನ್ನು ಪಡೆಯುವುದರಲ್ಲಿ ಆನಂದವಿದೆ, ಆದರೆ ಅದಕ್ಕಿಂತ\nಮುಖ್ಯವಾಗಿ ಅದನ್ನು ತೊರೆಯುವುದರಲ್ಲಿ ಹೆಚ್ಚಿನ ಆನಂದವಿದೆ. ಇದು ತಿಳಿದಾಗ ಬದುಕಿನ ಒಂದು ಮುಖ್ಯ\nಸೂತ್ರ ತಿಳಿದಂತೆ. ನಾವು ಬದುಕುವ ರೀತಿ ಎಂದರೆ “ನಾಳಿನ ಸುಖಕ್ಕಾಗಿ ಇಂದು ಕಷ್ಟಪಡುವುದು'. ಅಂದರೆ ಆ\nನಾಳೆ ಎಂದೂ ಬರುವುದಿಲ್ಲ. ಸಾಯುವ ತನಕ ನಾಳೆಗಾಗಿ ಕಷ್ಟಪಡುವುದು ನಮ್ಮ ಜೀವನವಾಗಬಾರದು.\nಭಗವಂತನನ್ನು ಪಡೆಯುವುದರಲ್ಲಿ ಮಹದಾನಂದವಿದೆ, ಹಾಗೂ ಅದು ನಮ್ಮನ್ನು ಸದಾ ಸುಖವಾಗಿಡುತ್ತದೆ\nಎನ್ನುವ ಸತ್ಯವನ್ನು ಕೃಷ್ಣ ಇಲ್ಲಿ ವಿವರಿಸಿದ್ದಾನೆ. ಒಮ್ಮೆ ನಾವು ನಮ್ಮ ಅಂತರಂಗದ ಆತ್ಮಸ್ವರೂಪದ ಸುಖವನ್ನು\nಅನುಭವಿಸಲು ಪ್ರಾರಂಭಿಸಿದರೆ, ಬಾಹ್ಯ ಸುಖದಲ್ಲಿ ಏನೂ ಇಲ್ಲ ಎನ್ನುವ ವಿಚಾರ ತಿಳಿಯುತ್ತದೆ. ನಮ್ಮೊಳಗೇ\nಆನಂದ ಅಡಗಿದೆ, ಅದು ಬಾಹ್ಯ ಸುಖದ ತ್ಯಾಗದಿಂದ ಕಾಣಬಹುದಾದ ಆನಂದ.\n\nನಮಗೆ ನಮ್ಮ ಒಳಗಿರುವ ಆನಂದ ಕೆಲವೊಮ್ಮೆ ಅನುಭವಕ್ಕೆ ಬರುತ್ತದೆ. ಒಮ್ಮೊಮ್ಮೆ \"ಅದೇಕೋ ಗೊತ್ತಿಲ್ಲ\nಆದರೆ ಬಹಳ ಖುಷಿ' ಎನ್ನುವ ಅನುಭವ ಪ್ರತಿಯೊಬ್ಬರೂ ಅನುಭವಿಸಿರುತ್ತಾರೆ. ಇದು ನಮ್ಮ ಅಂತರಂಗದ\nಆನಂದ ಉಕ್ಕಿ ಬರುವುದು. ಈ ಆನಂದವನ್ನು ಗುರುತಿಸಿ ಅದನ್ನು ಅನುಭವಿಸಲು ಕಲಿತಾಗ ಬಾಹ್ಯ ಸುಖ\nಕನಿಷ್ಠವಾಗಿ ಕಾಣಿಸುತ್ತದೆ. ಹೇಗೆ ನಿದ್ದೆಯಲ್ಲಿ ನಾವು ಬಾಹ್ಯ ಸುಖದ ಸ್ಪರ್ಶವಿಲ್ಲದೇ ನಮಗರಿವಿಲ್ಲದಂತೆ\nಆನಂದದಲ್ಲಿರುತ್ತೇವೋ ಹಾಗೇ ಎಚ್ಚರದಲ್ಲಿ ಅಂತರಂಗದ ಆನಂದವನ್ನು ಅನುಭವಿಸಲು ಕಲಿತುಕೊಳ್ಳಬೇಕು.\nಇದರಿಂದ ಬಾಹ್ಯ ಸುಖದ ಪ್ರಜ್ಞೆ ದೂರವಾಗುತ್ತದೆ.\n\nಉಪನಿಷತ್ತಿನಲ್ಲಿ ಹೇಳುವಂತೆ “ಬಾಹ್ಯ ಸುಖವನ್ನು ತ್ಯಾಗ ಮಾಡುವುದರಿಂದ, ಒಳಗಿನ ಆನಂದದ ಅರಿವು\nಮೂಡುತ್ತದೆ ಹಾಗೂ ಇದರಲ್ಲಿ ಅಮೃತತ್ವವಿದೆ”. ನಾವು “ಬೇಡ' ಎನ್ನುವುದರಲ್ಲಿ ಇರುವ ಆನಂದ “ಬೇಕು'\nಅನ್ನುವುದರಲ್ಲಿಲ್ಲ. ಬೇಕು ಎನ್ನುವುದು ಸದಾ ನಮಗೆ 'ಬೇಡಿ(ಸಂಕೋಲೆ)'. ಬೇಕು ಅನ್ನುವುದು ನಮ್ಮ ಮುಂದೆ\nಸಮಸ್ಯೆಗಳ ಸರಮಾಲೆಯನ್ನು ತಂದು ನಿಲ್ಲಿಸುತ್ತದೆ. “ಎಲ್ಲಾ ಬಾಹ್ಯ ಬಯಕೆಗಳನ್ನು ಕಳೆದುಕೊಳ್ಳುವುದರಲ್ಲೇ\nಮನುಷ್ಯನ ಆನಂದದ ಸೆಲೆ ಅಡಗಿದೆ” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಬೇಕುಗಳು ಕಮ್ಮಿ ಆದಂತೆ ಮನುಷ್ಯ ಆನಂದದಿಂದ\nಬದುಕುತ್ತಾನೆ.\n\nಕೇವಲ ಬಾಹ್ಯ ಸುಖವನ್ನು ಬಿಡುವುದಷ್ಟೇ ಅಲ್ಲ, ಅದರ ಜೊತೆಗೆ ಒಳಗಿನ ಆನಂದವನ್ನು ಹಿಡಿಯಬೇಕು. ಅದು\nಅನಂತವಾದ ಆನಂದ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಬ್ರಹ್ಮಯೋಗಯುಕ್ತಾತ್ಮಾ ಸುಖಮಕ್ಷಯಮಶ್ನುತೇ” ಎಂದು.\nಭಗವಂತನ ಧ್ಯಾನದಲ್ಲಿ ಒಳಗಿನಿಂದ ಆನಂದದ ಅನುಭವವಾಗುತ್ತದೆ- ಅದನ್ನು ಒಬ್ಬ ಸಾಧಕ ಪಡೆಯುತ್ತಾನೆ.\nಅಂತರಂಗದಲ್ಲಿ ಭಗವದ್‌ ಸ್ಪರ್ಶವಾಗಿ ಅದರಿಂದ ಅನಂತ ಸುಖವನ್ನು ಸಾಧಕ ನಿರಂತರ ಸವಿಯುತ್ತಾನೆ.\n\nಸುಖ ಎನ್ನುವುದು ನಮ್ಮೊಳಗೇ ಇದೆ. ಇದೊಂದು ಮಾನಸಿಕ ಸ್ಥಿತಿ. ನಾವು ನಮ್ಮೊಳಗಿನ ಸುಖವನ್ನು ಗುರುತಿಸದೆ\nಬಾಹ್ಯ ಸುಖದ ಬೆನ್ನು ಹತ್ತಿ ಕಷ್ಟ ಪಡುತ್ತೇವೆ. ಜಾನಪದ ಕಥೆಯೊಂದು ಹೀಗೆ ಹೇಳುತ್ತದೆ. ಒಬ್ಬ ಮುದುಕಿ ತನ್ನ\n\nಮನೆಯಲ್ಲಿ ರಾತ್ರಿ ಹೊತ್ತು ಸ್ವಲ್ಪ ಹಣವನ್ನು ಕೆಳಗೆ ಬೀಳಿಸಿಕೊಳ್ಳುತ್ತಾಳೆ. ಆದರೆ ಆಕೆಯ ಮನೆಯಲ್ಲಿ ದೀಪ\nಹಚ್ಚಲು ಎಣ್ಣೆ ಇರುವುದಿಲ್ಲ. ಬೀದಿಯಲ್ಲಿ ಬೀದಿದೀಪದ ಬೆಳಕನ್ನು ಕಂಡ ಮುದುಕಿ ಬೀದಿಯಲ್ಲಿ ಬಂದು ತಾನು\nಮನೆಯಲ್ಲಿ ಬೀಳಿಸಿಕೊಂಡ ಹಣವನ್ನು ಹುಡುಕುತ್ತಿರುತ್ತಾಳೆ. ಏಕೆ ಹೀಗೆ ಎಂದು ಕೇಳಿದಾಗ “ಮನೆಯಲ್ಲಿ ಬೆಳಕಿಲ್ಲ\nಆದರೆ ಇಲ್ಲಿ ಬೆಳಕಿದೆ ಅದಕ್ಕಾಗಿ ಇಲ್ಲಿ ಹುಡುಕುತ್ತಿದ್ದೇನೆ” ಎನ್ನುವುದು ಆ ಮುದುಕಿಯ ಉತ್ತರ! ನಾವೆಲ್ಲರೂ\nಹೀಗೇ. ನಿಜವಾದ ಆನಂದ ಇರುವುದು ಅಂತರಂಗದಲ್ಲಿ, ಆದರೆ ನಾವು ಸುಖವನ್ನು ಅರಸುವುದು\nಹೊರಪ್ರಪಂಚದಲ್ಲಿ!\n",
  "5.22": "ಯೇ ಹಿ ಸಂಸ್ಪರ್ಶ ಜಾಃ ಭೋಗಾಃ ದುಃಖ ಯೋನಯಃ ಏವ ತೇ |\nಆದಿ ಅಂತ ವಂತಃ ಕೌಂತೇಯ ನ ತೇಷು ರಮತೇ ಬುಧಃ -ವಿಷಯದ ನಂಟಿನಿಂದ ಬರುವ ಸುಖಗಳು ಬನ್ನ ದ\nತವರು. ಬಂತು ಎನ್ನು ವಷ್ಟ ರಲ್ಲೇ ಬರಿದಾಗುವಂಥವು. ಕೌಂತೇಯಾ, ಬಲ್ಲವರು ಅವನ್ನು ಮೆಚ್ಚುವುದಿಲ್ಲ.\n\nಬಾಹ್ಯ ವಿಷಯಸ್ಪರ್ಶದಿಂದ ಸಿಗುವ ಸುಖಭೋಗದ ಅನುಭವ(ಸಂಸ್ಪರ್ಶ)ದಿಂದ ನಮಗೆಷ್ಟು ಸುಖ ಸಿಕ್ಕೀತು?\nಒಂದು ಗುಲಗಂಜಿಯಷ್ಟು ಸುಖಕ್ಕಾಗಿ ಕುಂಬಳಕಾಯಿಯಷ್ಟು ದುಃಖವನ್ನು ಅನುಭವಿಸಲು ನಾವು\nಸಿದ್ಧರಾಗಿರುತ್ತೇವೆ. ಇಂದಿನ ಎಲ್ಲಾ ಪ್ರಾಪಂಚಿಕ ಅಪರಾಧಗಳಿಗೆ ಇದೇ ಕಾರಣ. ಕ್ಷಣಿಕ ಸುಖದ ಆಸೆಗೆ ಬಿದ್ದು\nಇಡೀ ಜೀವನವನ್ನೇ ಹಾಳು ಮಾಡಿಕೊಳ್ಳುವವರನ್ನು ನಮ್ಮ ದೈನಂದಿನ ಜೀವನದಲ್ಲಿ ನಾವು ಕಾಣುತ್ತೇವೆ.\nನಮಗೆ ಬಾಹ್ಯವಾಗಿ ಸುಖ ಎಂದು ಕಾಣುವುದು ದುಃಖವನ್ನು ಮರಿ ಹಾಕುವ ಮೊಟ್ಟೆ ಎನ್ನುವ ಸತ್ಯವನ್ನರಿಯದೇ,\nಅದೇ ಸುಖ ಎಂದು ಅದರ ಬೆನ್ನು ಹಿಡಿಯುತ್ತೇವೆ. ಪ್ರತಿಯೊಂದು ಬಾಹ್ಯಸುಖದ ಹಿಂದೆ ದುಃಖವೆಂಬ ಕಗ್ಗತ್ತಲು\nಮಡುಗಟ್ಟಿರುತ್ತದೆ. ಬಾಹ್ಯ ಸುಖ-ಆನಂದ ಎನ್ನುವುದು ಕೇವಲ ಒಂದು ಮಿಂಚು. ಅದು ಬಂತು ಎನ್ನುವಷ್ಟರಲ್ಲಿ\nಬರಿದಾಗುತ್ತದೆ. ತಿಳುವಳಿಕೆ ಉಳ್ಳವರು ಈ ಬಾಹ್ಯ ಸುಖದ ಆಸೆಯಲ್ಲಿ ಬದುಕುವುದಿಲ್ಲ.\n\nಅಧ್ಯಾತ್ಮದ ಬಗ್ಗೆ ಕೆಲವರು ಹೇಳುವುದಿದೆ: “ಈಗಲೇ ನಮಗೇಕೆ ಅಧ್ಯಾತ್ಮ; ಅದೆಲ್ಲಾ ಅರವತ್ತರ ಶಾಂತಿ ಆದ\nಮೇಲೆ” ಎಂದು. ಇದು ಏಕೆ ಸರಿಯಲ್ಲ ಎನ್ನು ವುದನ್ನು ಕೃಷ್ಣ ಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ವಿವರಿಸುತ್ತಾನೆ.",
  "5.23": "ಶಕ್ನೊ ತಿ ಇಹ ಏವ ಯಃ ಸೋಢುಮ್‌ ಪ್ರಾಕ್‌ ಶರೀರ ವಿಮೋಕ್ಷಣಾತ್‌\n\nಕಾಮ ಕ್ರೋಧ ಉದ್ಭ ವಮ್‌ ವೇಗಮ್‌ ಸಃ ಯುಕ್ತಃ ಸಃ ಸುಖೀ ನರಃ -ಒಲುಮೆ-ಸಿಡುಕುಗಳ ಸೆಳೆತವನ್ನು ಇಲ್ಲೇ,\nಈ ನರದೇಹ ಕಳಚುವ ಮುನ್ನವೇ ಯಾರು ತಾಳಬಲ್ಲನೋ ಅಂತಹ ಮಾನವನೇ ನಿಜವಾದ ಯೋಗಿ;\nನಿಜವಾದ ಸುಖಿ.\n\nನಾವು ನಮ್ಮ ಪ್ರಾಪಂಚಿಕ ಸುಖ-ಸ್ಪರ್ಶದ ಮೋಹವನ್ನು ಗೆಲ್ಲಲು ಸಾಧ್ಯವಾಗುವುದು ಈ ದೇಹ ಇರುವಾಗಲೇ.\nವಿಷಯಗಳ ಸ್ಪರ್ಶ ಇರುವುದು ದೇಹಕ್ಕೆ ಹಾಗೂ ವಿಷಯಗಳನ್ನು ಗೆಲ್ಲಲು ಸಾಧ್ಯವಾಗುವುದು ಈ\nದೇಹವಿರುವಾಗಲೇ. ಭಗವಂತ ನಮಗೆ ಯಾವುದು ಸರಿ, ಯಾವುದು ತಪ್ಪು ಎನ್ನುವ ವಿಚಾರ ಮಾಡುವ\nಬುದ್ಧಿಶಕ್ತಿಯನ್ನು ಕೊಟ್ಟಿದ್ದಾನೆ. ಇಂತಹ ವಿಚಾರ ಶಕ್ತಿಯನ್ನು ಬಳಸಿಕೊಂಡು ಶರೀರ ಬಿದ್ದುಹೋಗುವ ಮೊದಲೇ\nಇಂದ್ರಿಯ ನಿಗ್ರಹವನ್ನು ಅಭ್ಯಾಸ ಮಾಡಬೇಕು. ಇದು ಮುಂದಕ್ಕೆ ಹಾಕುವ ಮತ್ತು ಒಂದು ದಿನದಲ್ಲಿ ಸಾಧಿಸುವ\nವಿಷಯವಲ್ಲ. ಇದಕ್ಕೆ ನಿರಂತರ ಸಾಧನೆ ಅಗತ್ಯ. ಈ ದೇಹ ಗಟ್ಟಿಯಾಗಿರುವಾಗಲೇ ಈ ಸಾಧನೆ ಮಾಡಬೇಕು.\n\nಮನುಷ್ಯನನ್ನು ಕಾಡುವ ಮೂಲಭೂತ ಸಮಸ್ಯೆ ಕಾಮ ಮತ್ತು ಕ್ರೋಧ. ಈ ಕಾಮ ಕ್ರೋಧದ ವೇಗ ನಮ್ಮೆಲ್ಲಾ\nವಿವೇಕವನ್ನು ತಳ್ಳಿ ಮುಂದೆ ಬಂದು ನಿಲ್ಲುವಷ್ಟು ಬಲಿಷ್ಠ. ಅದು ಮಳೆಗಾಲದ ಹುಚ್ಚು ಹೊನಲಂತೆ ನಿನ್ನ\nವಿಚಾರಧಾರೆಯನ್ನು ಕೊಚ್ಚಿಕೊಂಡು ಹೋಗುವ ಮೊದಲು ಅದನ್ನು ತಡೆ. ಯಾರು ಇದನ್ನು ತಡೆಯಬಲ್ಲರೋ\nಅವರು “ಸ ಯುಕ್ತಃ ಸ ಸುಖೀ ನರಃ” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ... ಯಾರು ಕಾಮ-ಕ್ರೋಧದ ಬೆನ್ನುಹತ್ತದೇ, ಬಾಹ್ಯ\nಸ್ಪರ್ಶವನ್ನು ತಡೆದು ಅಂತರಂಗದ ಅನುಭವಕ್ಕೆ ತನ್ನನ್ನು ತಾನು ಒಡ್ಡಿಕೊಳ್ಳುತ್ತಾನೋ ಅವನು ನಿಜವಾದ ಸುಖಿ.\n\nನಮ್ಮ ಅಂತರಂಗದ ಅನುಭವ ಎಂತಾದ್ದು? ಒಬ್ಬ ಸಾಧಕ ತನ್ನ ಅಂತರಂಗದಲ್ಲಿ ಕಾಣತಕ್ಕಂತಹ ಆನಂದದ\nಅನುಭವವೇನು ಎನ್ನುವುದನ್ನು ಕೃಷ್ಣ ಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ವಿವರಿಸಿದ್ದಾನೆ.",
  "5.24": "ಯಃ ಅಂತಃ ಸುಖಃ ಅಂತಃ ಆರಾಮಃ ತಥಾ ಅಂತಃ ಜ್ಯೋತಿಃ ಏವಯಃ ।\n\nಸಃ ಯೋಗೀ ಬ್ರಹ್ಮ ನಿರ್ಬಾಣಂ ಬ್ರಹ್ಮಭೂತಃ ಅಧಿಗಚ್ಛತಿ-ಬಯಕೆಯಳಿದು ಒಳಬಗೆಯ ಸುಖ ಕಂಡವನು,\nಭಗವಂತನನ್ನು ಕಂಡು ಒಳಗೊಳಗೇ ಖುಷಿಗೊಂಡವನು, ಭಗವಂತನ ಬೆಳಕನ್ನೇ ಒಳಗೆಲ್ಲಾ\nತುಂಬಿಕೊಂಡವನು, ಭಗವಂತನಲ್ಲೇ ನೆಲೆ ನಿಂತ ಇಂತಹ ಸಾಧಕ, ಅಳಿವಿರದ ಮೈ ತಳೆದ ಭಗವಂತನನ್ನೇ\n\nಸೇರುತ್ತಾನೆ.\n\nಮನುಷ್ಯ ಸುಖ ಬೇಕು ಎಂದು ಬಯಸದೇ ಅಂತಃಸುಖ ಬೇಕು ಎಂದು ಬಯಸಬೇಕು. ಈ ಶ್ಲೋಕದಲ್ಲಿ 'ಸುಖ'\nಮತ್ತು \"ಆರಾಮ' ಎನ್ನುವ ಎರಡು ಶಬ್ದಗಳು ಬಳಕೆಯಾಗಿವೆ. ಈ ಎರಡು ಶಬ್ದಗಳ ನಡುವೆ ಸೂಕ್ಷ್ಮ ವ್ಯತ್ಯಾಸವಿದೆ.\nನಮ್ಮ ಬಯಕೆಗಳು ಈಡೇರುವುದು ಅಥವಾ ಬಯಸಿದ್ದು ಸಿಕ್ಕಿದಾಗ ಆಗುವುದು “ಆರಾಮ' ; ಬಯಕೆಗಳೇ\n\nಇಲ್ಲದಿರುವುದು ಸುಖ. ಯಾವುದೋ ಕೊರತೆ, ತೊಂದರೆ, ಕಷ್ಟ ಪರಿಹಾರವಾದಾಗ, ಯಾವುದೋ\nತಾಪತ್ರಯದಿಂದ ಪಾರಾದಾಗ ಆಗುವುದು ಸುಖ. ಇಲ್ಲಿ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಅಧ್ಯಾತ್ಮ ಯೋಗದ ಸಾಧಕ,\nಸಾಧನೆ ಮಾಡಿ ಫಲ ಪಡೆದವನು, ಮಾನಸಿಕವಾಗಿ ಭಗವಂತನಲ್ಲೇ ನೆಲೆಸಿರುತ್ತಾನೆ. ಆತ ಒಳಗಿಂದೊಳಗೆ\nಆರಾಮವಾಗಿರುತ್ತಾನೆ” ಎಂದು. ಸಾಧಕ ಅಂತರಂಗದಲ್ಲಿ ಭಗವಂತನನ್ನು ನೋಡುತ್ತಾ-\nಆರಾಮವಾಗಿರುತ್ತಾನೆ; ಕಾಮ ಕ್ರೋಧವನ್ನು ಬಿಟ್ಟು-ಸುಖಪಡುತ್ತಾನೆ; ತನ್ನೊ ಳಗಿರುವ ಆ ಜ್ಯೋತಿಯನ್ನು\nಅರಿತು ತನ್ನೊಳಗಿರುವ ಆ ಮಹಾ ಬೆಳಕಾದ ಭಗವಂತನನ್ನು ಕಂಡು ಭಗವಂತನಲ್ಲೇ ನೆಲೆಸಿಬಿಡುತ್ತಾನೆ.\n",
  "5.25": "ಲಭಂತೇ ಬ್ರಹ್ಮನಿರ್ಬಾಣಮ್‌ ಋಷಯಃ ಕ್ಷೀಣ ಕಲ್ಮಷಾಃ |\nಛಿನ್ನ ದ್ವೈಧಾಃ ಯತಆತ್ಮಾನಃ ಸರ್ವಭೂತಹಿತೇ ರತಾಃ -ಕೊಳೆಗಳನ್ನೆಲ್ಲ ಕಳೆದು, ಇಬ್ಬಂದಿತನವಳಿದು,\n\nತಿಳಿವಿನ ಕೊಳವಾದವರು.[ಬಗೆಯನ್ನು ಹದಗೊಳಿಸಿದವರು], ಎಲ್ಲಾ ಜೀವಿಗಳಿಗೂ ಒಳಿತನ್ನೇ ಬಯಸುವ\nಬಲ್ಲವರು ನಿತ್ಯ ಸ್ವರೂಪನಾದ ಭಗವಂತನನ್ನೇ ಪಡೆಯುತ್ತಾರೆ.\n\nತನ್ನೊಳಗೆ ಉದ್ಭವವಾಗುವ ಸಂದೇಹವನ್ನು, ದ್ವಂದ್ವವನ್ನು ಮೀರಿ ನಿಂತವರು ನಿಜವಾದ ಸಾಧಕರು. ಇವರು\nಸದಾ ತಮ್ಮ ಮನಸ್ಸನ್ನು ಅಂತರಂಗದಲ್ಲಿ ನೆಲೆಗೊಳಿಸಿರುತ್ತಾರೆ. ಇವರು ಬಯಸುವ ಸುಖ 'ಅಂತರಂಗದ\nಸುಖ'. ಬಾಹ್ಯ ಸುಖದ ಬೆನ್ನುಹತ್ತದೇ, ಎಲ್ಲಾ ಜೀವಿಗಳಿಗೆ ಒಳಿತನ್ನೇ ಬಯಸುವ ಇವರು ಸದಾ ನಿತ್ಯ\nಸ್ವರೂಪನಾದ ಭಗವಂತನಲ್ಲೇ ನೆಲೆಸಿ ಅವನನ್ನೇ ಸೇರುತ್ತಾರೆ.\n",
  "5.26": "ಕಾಮ ಕ್ರೋಧ ವಿಯುಕ್ತಾನಾಮ್‌ ಯತೀಸಾಮ್‌ ಯತಚೇತಸಾಮ್‌ |\n\nಅಭಿತಃ ಬ್ರಹ್ಮನಿರ್ಬಾಣಮ್‌ ವರ್ತತೇ ವಿದಿತ ಆತ್ಮನಾಮ್‌... ಪ್ರಯತ್ನಶೀಲರಾಗಿ ಒಲುಮೆ-ಸಿಡುಕುಗಳನ್ನು\nಒದ್ದವರಿಗೆ, ಬಗೆಯನ್ನು ಗೆದ್ದವರಿಗೆ, ಭಗವಂತನನ್ನು ಬಲ್ಲವರಿಗೆ ಎಲ್ಲೆಡೆಯೂ ನಿತ್ಯ ಸ್ವರೂಪನಾದ ಭಗವಂತ\nತುಂಬಿರುತ್ತಾನೆ.\n\nಕಾಮ-ಕ್ರೋಧವನ್ನು ಸಂಪೂರ್ಣ ತೊರೆದು, ಪೂರ್ಣವಾಗಿ ಇಂದ್ರಿಯನಿಗ್ರಹ ಸಾಧಿಸಿದವರಿಗೆ ಎಲ್ಲೆಡೆಯೂ ಎಲ್ಲಾ\nಜೀವ ಜಂತುವಿನಲ್ಲೂ ಭಗವಂತ ಕಾಣಿಸುತ್ತಾನೆ. ಯಾವುದೇ ಐಹಿಕ ಕ್ಲೇಶದ ನೋವು ಇವರಿಗಿರುವುದಿಲ್ಲ. ಇವರ\nಮನದಲ್ಲಿ ಸರ್ವಾಂತರ್ಯಾಮಿಯಾದ, ನಿತ್ಯ ಸ್ವರೂಪನಾದ ಭಗವಂತ ನೆಲೆನಿಂತಿರುತ್ತಾನೆ.\n\nಬಾಹ್ಯ ಸುಖದಿಂದ ಅಂತರಂಗದ ಸ್ವರೂಪಭೂತವಾದ ಸಹಜ ಸುಖದ ಕಡೆ ತಿರುಗುವ ಸಂದೇಶವನ್ನು ಕೊಟ್ಟ\nಕೃಷ್ಣ, ಅದಕ್ಕೆ ಪೂರಕವಾದ ಧ್ಯಾನದ ಬಗ್ಗೆ ಸಂಕ್ಷಿಪ್ತವಾಗಿ ಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ವಿವರಿಸುತ್ತಾನೆ.\n\nಸ್ಪರ್ಶಾನ್‌ ಕೃತ್ವಾ ಬಹಿರ್ಬಾಹ್ಯಾಂಶ್ಚಕ್ಷುಶ್ಚವಾಂತರೇ ಭ್ರುವೋಃ ।\n\nಪ್ರಾಹಾಪಾನೌ ಸಮೌ ಕೃತ್ವಾ ನಾಸಾಭ್ಯಂತರಚಾರಿಣೌ",
  "5.27": "ಯತೇಂದ್ರಿಯಮನೋವೃತ್ತಿರ್ಮುನಿರ್ಮೋಕ್ಷಪರಾಯಣಃ |\nವಿಗತೇಚ್ಛಾಭಯಕ್ರೋಧೋ ಯಃ ಸದಾ ಮುಕ್ತ ಏವ ಸಃ",
  "5.28": "ಸ್ಪರ್ಶಾನ್‌ ಕೃತ್ವಾ ಬಹಿಃ ಬಾಹ್ಯಾನ್‌ ಚಕ್ಷುಃ ಚ ಏವ ಅಂತರೇ ಭ್ರುವೋಃ ।\n\nಪ್ರಾಣ ಅಪಾನೌ ಸಮೌ ಕೃತ್ವಾ ನಾಸ ಅಭ್ಯಂತರ ಚಾರಿಣೌ |\n\nಯತ ಇಂದ್ರಿಯ ಮನಃ ವೃತ್ತಿಃ ಮುನಿಃ ಮೋಕ್ಷ ಪರಾಯಣಃ |\n\nವಿಗತ ಇಚ್ಛಾ ಭಯ ಕ್ರೋಧಃ ಯಃ ಸದಾ ಮುಕ್ತಃ ಏವ ಸಃ -ಹೊರಗಣ ವಿಷಯ ಸಂಬಂಧಗಳನ್ನು ಹೊರಗಟ್ಟಿ,\nನೋಟವನ್ನು ಹುಬ್ಬುಗಳ ನಡುವಿರಿಸಿ, ಹೊರಳೆಯೊಳಗೆ ಚಲಿಸುವ ಪ್ರಾಹಾಪಾನಗಳನ್ನು ಕುಂಭಕದಲ್ಲಿ\nಸಮಗೊಳಿಸಿ, ಇಂದ್ರಿಯಗಳ ಮತ್ತು ಮನದ ಚಲ್ಲಾಟವನ್ನು ಹಿಡಿತದಲ್ಲಿಟ್ಟವನು, ಬಿಡುಗಡೆಗಾಗಿ\nಕಾತರಿಸುವವನು, ಬಯಕೆ-ಅಂಜಿಕೆ-ಸಿಡುಕುಗಳನ್ನು ತೊಡೆದುಕೊಂಡವನು. ಇಂತಹ ಸಾಧಕನು ಸದಾ\nಮುಕ್ತನೇ ಸರಿ.\n\nನಾವು ನಮ್ಮ ಮನಸ್ಸನ್ನು ನಿಯಂತ್ರಿಸಬೇಕಾದರೆ ಮೊದಲು ನಮ್ಮ ಇಂದ್ರಿಯಗಳು ಹೊರ ಪ್ರಪಂಚದಲ್ಲಿ\nಸಂಚರಿಸುವುದನ್ನು ನಿಯಂತ್ರಿಸಬೇಕು. “ಸ್ಪರ್ಶಾನ್‌ ಕೃತ್ವಾ ಬಹಿಃ ಬಾಹ್ಯಾನ್‌”- ಬಾಹ್ಯೇಂದ್ರಿಯ ನಿಯಂತ್ರಣ\nಮಾಡದೇ ಮನಸ್ಸನ್ನು ನಿಯಂತ್ರಣ ಮಾಡಲು ಸಾಧ್ಯವಿಲ್ಲ. ಇದಕ್ಕಾಗಿ ಹೊರ ಪ್ರಪಂಚದ ರೂಪ-ರಸ-ಸ್ಪರ್ಶ-\nಶಬ್ದ-ಗಂಧ ಎನ್ನುವ ಸುಖದ ಭ್ರಮೆಯನ್ನು ಹೊರಗೇ ಬಿಡಬೇಕು. ಜೊತೆಗೆ ಅನಪೇಕ್ಷಿತವಾಗಿ ನಮ್ಮೊಳಗೆ\nತುಂಬಿರುವ, ಸತ್ಯವನ್ನು ಕಾಣುವುದಕ್ಕೆ ಅಡ್ಡಗೋಡೆಯಾಗಿರುವ, ಈ ಪ್ರಪಂಚದ ಅನುಭೂತಿಯನ್ನು\nಹೊರಹಾಕಬೇಕು. ಸಾಮಾನ್ಯವಾಗಿ ನಮಗೆ ಧ್ಯಾನಕ್ಕೆ ಕುಳಿತಾಗ ಏನೇನೊ ಕಾಣಲು ಆರಂಭವಾಗುತ್ತದೆ.\nಸುಂದರವಾದದ್ದು, ಭಯಾನಕವಾದದ್ದು, ಇತ್ಯಾದಿ. ಇದಕ್ಕಾಗಿ ಭಯಪಡುವ ಅಗತ್ಯವಿಲ್ಲ. ಇವೆಲ್ಲವೂ ನಾವು\nನಮ್ಮೊಳಗೆ ತುಂಬಿಕೊಂಡಿರುವ ಅನಗತ್ಯ ವಿಚಾರಗಳು. ಅವು ಹೊರ ಹೋಗುವಾಗ ಈ ರೀತಿ ನಮಗೆ ದರ್ಶನ\nಕೊಡುತ್ತವೆ. ಹಠಬಿಡದೆ ಸಾಧನೆ ಮುಂದುವರಿಸಿದಾಗ ಕ್ರಮೇಣವಾಗಿ ಈ ಎಲ್ಲಾ ವಿಚಾರಗಳು ಹೊರಹೋಗಿ\nಮನಸ್ಸು ನಿರ್ಮಲವಾಗುತ್ತದೆ. ಇದು ಒಂದೇ ದಿನದಲ್ಲಿ ಆಗುವಂತದ್ದಲ್ಲ, ಇದಕ್ಕೆ ನಿರಂತರ ಸಾಧನೆ ಅಗತ್ಯ.\nಒಮ್ಮೆ ಅಂತಃಕರಣ ಸ್ವಚ್ಛವಾದರೆ ಅದರಲ್ಲಿ ಏನನ್ನು ಬೇಕಾದರೂ ಪ್ರತಿಬಿಂಬಿಸಬಹುದು.\n\nಧ್ಯಾನಕ್ಕೆ ಬೇಕಾದ ಇನ್ನೊಂದು ಮುಖ್ಯವಾದ ಅಂಶ ಅನ್ನಮಯಕೋಶ(ದೇಹ) ಸ್ಥಿರಗೊಳಿಸುವುದು. ದೇಹ\nಚಲಿಸಿದರೆ ಮನಸ್ಸು ಚಲಿಸುತ್ತದೆ-ಆಗ ಏಕಾಗ್ರತೆ ಸಾಧ್ಯವಿಲ್ಲ. ಅದಕ್ಕಾಗಿ ನಾವು ನೆಟ್ಟಗೆ(erect and straight body), ನಮಗೆ ಸಾಧ್ಯವಾದ ಆಸನ(Posture)ದಲ್ಲಿ ನಮ್ಮ ದೇಹವನ್ನು ಸ್ಥಿರಗೊಳಿಸಬೇಕು. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ:\n“ಚಕ್ಷುಃ ಚ ಏವ ಅಂತರೇ ಭ್ರುವೋಃ” ಎಂದು. ಅಂದರೆ ನಮ್ಮ ದೃಷ್ಟಿಯನ್ನು ನಮ್ಮ ಎರಡು ಹುಬ್ಬಿನ ನಡುವೆ\nನೆಡುವುದು.ಇದು. ಕಷ್ಟವಾದರೆ ಮೂಗಿನ ತುದಿಯನ್ನೂ ಆರಿಸಿಕೊಳ್ಳಬಹುದು ಎಂದು ಶಾಸ್ತ್ರಕಾರರು\nಹೇಳುತ್ತಾರೆ). ನಮ್ಮ ಎರಡು ಹುಬ್ಬಿನ ನಡುವೆ ಆಜ್ಞಾಚಕ್ರವಿದೆ, ಅಲ್ಲಿ ನಾವು ನಮ್ಮ ದೃಷ್ಟಿಯನ್ನು ನೆಟ್ಟಾಗ ಈ ಶಕ್ತಿ\nಕೇಂದ್ರ ಜಾಗೃತವಾಗುತ್ತದೆ. ಇದರಿಂದ ಅನ್ನಮಯ ಕೋಶ ಸ್ಥಿರವಾಗುತ್ತದೆ.\n\nಅನ್ನಮಯಕೋಶದ ನಂತರ ಪ್ರಾಣಮಯಕೋಶ. “ಪ್ರಾಣ ಅಪಾನೌ ಸಮೌ ಕೃತ್ವಾ ನಾಸ ಅಭ್ಯಂತರ\nಚಾರಿಣೌ”-ನಮ್ಮೊಳಗೆ ನಿರಂತರ ವಾಯುವಿನ ಚಲನೆ ಇರುತ್ತದೆ; ಈ ಚಲನೆಯನ್ನು ಸ್ಥಿರಗೊಳಿಸುವುದನ್ನು\nಕುಂಭಕ ಎನ್ನುತ್ತಾರೆ. ಇದರಲ್ಲಿ ಎರಡು ವಿಧ. ಒಂದು ಅಂತಃಕುಂಭಕ ಹಾಗೂ ಇನ್ನೊಂದು ಬಾಹ್ಯಕುಂಭಕ.\nಅಂತಃಕುಂಭಕದಲ್ಲಿ ಮೊದಲು ಸಂಪೂರ್ಣ ಒಳಗಿರುವ ಗಾಳಿಯನ್ನು ಹೊರಹಾಕಿ ನಂತರ ಎಷ್ಟು ಹೆಚ್ಚು\nಸಾಧ್ಯವೋ ಅಷ್ಟು ಶುದ್ಧ ಗಾಳಿಯನ್ನು ಒಳಗೆ ತೆಗೆದುಕೊಂಡು, ಉಸಿರನ್ನು ಸ್ಥಗನಗೊಳಿಸಬೇಕು. [ಈ ರೀತಿಯ\nಪ್ರಾಣಾಯಾಮವನ್ನು ಗುರುವಿನಿಂದ ಕಲಿತು. ಮಾಡಬೇಕು- ಇಲ್ಲದಿದ್ದರೆ ಇದರಿಂದ ಅಪಾಯವಿದೆ].\nಬಾಹ್ಯಕುಂಭಕದಲ್ಲಿ ಒಳಗಿನ ಗಾಳಿಯನ್ನು ಸಂಪೂರ್ಣ ಹೊರಹಾಕಿ ಅದೇ ಸ್ಥಿತಿಯಲ್ಲಿ ಉಸಿರನ್ನು\nಸ್ಥಗನಗೊಳಿಸುತ್ತಾರೆ. ಸಾಮಾನ್ಯವಾಗಿ ಹೃದಯ ರೋಗವಿದ್ದವರಿಗೆ ಅಂತಃಕುಂಭಕ ಅಪಾಯಕಾರಿ. ಅವರು\nಬಾಹ್ಯಕುಂಭಕ ಮಾಡಬಹುದು. ಹೀಗೆ ಕುಂಭಕದಿಂದ ಪ್ರಾಣಮಯಕೋಶ ಸ್ಥಿರವಾಗುತ್ತದೆ. ನಂತರದ ಹೆಜ್ಜೆ\nಮನೋಮಯ ಮತ್ತು ವಿಜ್ಞಾನಮಯಕೋಶ. ನಮ್ಮ ಮನಸ್ಸು ಚಂಚಲ, ಅದು ಒಂದುಕಡೆ ನಿಲ್ಲುವುದಿಲ್ಲ, ಅದನ್ನು\nಸ್ಥಿರಗೊಳಿಸಬೇಕು. “ಈ ದಾರಿಯಲ್ಲಿ ನಾನು ಸಾಗಿ-ಸಾಧಿಸಿ ಸಿದ್ಧಿ ಪಡೆದೇ ಪಡೆಯುತ್ತೇನೆ' ಎನ್ನುವ ಹಠತೊಟ್ಟು\nಮನಸ್ಸನ್ನು ಅದಕ್ಕೆ ಅಣಿಗೊಳಿಸಬೇಕು. ಇದರಿಂದ ಚಿತ್ತ ಭಗವಂತನ ಕಡೆ ಏಕಾಗ್ರವಾಗುತ್ತದೆ. ಈ ಸ್ಥಿತಿ\nಪಾಂಚಭೌತಿಕವಾಗಿ ನಾವು ತಲುಪಬಹುದಾದ ಅತ್ಯಂತ ಮಹತ್ತಾದ ಸ್ಥಿತಿ. ಇಲ್ಲಿರುವ ಆನಂದ ಅಪರಿಮಿತ. ಈ\nಸ್ಥಿತಿಯಲ್ಲಿರುವ ಸುಖವನ್ನು ಅನುಭವಿಸಿದರೆ ಮುಂದೆ ಬಾಹ್ಯ ಪ್ರಪಂಚದಲ್ಲಿನ ಸುಖದ ಹಿಂದೆ ನಮ್ಮ ಮನಸ್ಸು\nಎಂದೂ ಹರಿಯುವುದಿಲ್ಲ.ಮನಸ್ಸು ಭಗವಂತನಲ್ಲಿ ನೆಲೆನಿಲ್ಲುತ್ತದೆ. ಇದರಿಂದ ನಮ್ಮ ಆಸೆ-ಭಯ-ಕ್ರೋಧ ಎಲ್ಲವೂ\nಇಲ್ಲವಾಗುತ್ತದೆ. “ಇಂತಹ ಸಾಧಕ ಸದಾ ಮುಕ್ತನೇ ಸರಿ” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.\n\nಅನ್ನಮಯಕೋಶ, ಪ್ರಾಣಮಯಕೋಶ, ಮನೋಮಯಕೋಶ ಮತ್ತು ವಿಜ್ಞಾನಮಯಕೋಶವೆಂಬ\nಚತುರ್ವಿದ ಅಂತಃಕರಣವನ್ನು ಪಕ್ವಗೊಳಿಸಿ ಹೇಗೆ ನಾವು ನಮ್ಮೊಳಗಿನ ಭಗವಂತನ ದರ್ಶನವನ್ನು\nಪಡೆಯಬಹುದು ಎನ್ನುವುದನ್ನು ವಿವರಿಸಿದ ಕೃಷ್ಣ, . ಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ನಾವೆಂದೂ ಕಾಣದ ಆ\nಭಗವಂತನನ್ನು ಯಾವ ರೀತಿ ಕಾಣಬೇಕು ಎನ್ನುವುದನ್ನು ವಿವರಿಸುತ್ತಾನೆ.\n",
  "5.29": "ಭೋಕ್ಪಾರಮ್‌ ಯಜ್ಞ ತಪಸಾಮ್‌ ಸರ್ವಲೋಕ ಮಹೇಶ್ವರಮ್‌ ।\n\nಸುಹೃದಮ್‌ ಸರ್ವ ಭೂತಾನಾಮ್‌ ಜ್ಞಾತ್ವಾ ಮಾಮ್‌ ಶಾಂತಿಮ್‌ ಖಚ್ಛತಿ -- ಹೋಮಗಳನ್ನು-ವೃತಗಳನ್ನು\nಉಣ್ಣುವವನೆಂದು, ಎಲ್ಲಾ ಲೋಕಗಳ ಒಡೆಯರಿಗೂ ಹಿರಿಯೊಡೆಯನೆಂದು, ಎಲ್ಲಾ ಜೀವಿಗಳ ನೇಹಿಗನೆಂದು\nನನ್ನನ್ನು ತಿಳಿದವನು ಸುಖದ ಸೆಲೆಯಾದ ಮುಕ್ತಿಯನ್ನು ಪಡೆಯುತ್ತಾನೆ.\n\nಆ ಭಗವಂತ ಸರ್ವ ಯಜ್ಞಗಳ ಭೋಕ್ತಾರ. [ಇಲ್ಲಿ ಯಜ್ಞ ಅಂದರೆ ಅಗ್ನಿಮುಖದಲ್ಲಿ ಮಾಡುವ ಯಜ್ಞ ಮಾತ್ರವಲ್ಲ,\nಹಿಂದೆ ವಿವರಿಸಿದ ಎಲ್ಲಾ ರೀತಿಯ ಯಜ್ಞ]. ನಾವು ಯಜ್ಞದಲ್ಲಿ ದೇವತೆಗಳ ಹೆಸರಿನಲ್ಲಿ ಅರ್ಪಿಸುವ ಹವಿಸ್ಸೂ\nಕೂಡಾ ಆ ದೇವತೆಯೊಳಗೆ ಅಂತರ್ಯಾಮಿಯಾಗಿರುವ ಭಗವಂತನಿಗೆ ಅರ್ಪಿತ ಎನ್ನುವ ಭಾವನೆಯಿಂದ\nಅರ್ಪಿಸಬೇಕು. ಭಗವಂತನಿಗೆ ಅರ್ಪಿಸದೇ ಅರ್ಪಿಸುವ ಯಾವ ಹವಿಸ್ಸನ್ನೂ ದೇವತೆಗಳು ಸ್ವೀಕರಿಸುವುದಿಲ್ಲ.\nನಮ್ಮ ಪ್ರತಿಯೊಂದು ನಡೆಯಲ್ಲಿಯೂ ಭಗವಂತನ ಅನುಸಂಧಾನವಿರಬೇಕು. ಆತ ಸರ್ವಸಮರ್ಥ,\nಸರ್ವಕ್ರಿಯೆಗಳ ನಿಯಾಮಕ, ಎಲ್ಲವೂ ಅವನಿಗೆ ಸಂದದ್ದು ಎನ್ನುವ ಅನುಸಂಧಾನ ಧ್ಯಾನದಲ್ಲಿ ಬಹಳ ಮುಖ್ಯ.\nದೈಹಿಕವಾಗಿ, ಮಾನಸಿಕವಾಗಿ, ವಾಚಕವಾಗಿ ಅಚಲವಾದ ದೀಕ್ಷೆ ಇರಬೇಕು. ಯಾವ ಕಾಲಕ್ಕೂ\nಅಪ್ರಾಮಾಣಿಕನಾಗಿ ಮಾತನಾಡುವುದಿಲ್ಲ ಎನ್ನುವ ದೀಕ್ಷೆ, ಸದಾ ಮನಸ್ಸಿನಲ್ಲಿ ಸತ್ಯದ ಬಗ್ಗೆ ಆಳವಾದ ಚಿಂತನೆ,\nಸದಾ ಎಲ್ಲರ ಬಗ್ಗೆ ಸದ್ಭಾವ- ಹೀಗೆ ಇದೊಂದು ತಪಸ್ಸು. ನಾವು ಭಗವಂತನನ್ನು ಮರೆತು ಯಾರನ್ನು\nಪೂಜಿಸಿದರೂ ಅದು ವ್ಯರ್ಥ.\n\nಕೆಲವರಿಗೆ ಭಗವಂತ ಎಂದರೆ ಭಯ! ಇಲ್ಲಿ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: 'ಸುಹೃದಮ್‌ ಸರ್ವ ಭೂತಾನಾಮ್‌' ಎಂದು.\nಭಗವಂತನ ಬಗ್ಗೆ ಎಂದೂ ಭಯಪಡಬೇಕಾಗಿಲ್ಲ. ಆತನಿಗಿಂತ ಆತ್ಮೀಯ ಗೆಳೆಯ ಇನ್ನೊಬ್ಬನಿಲ್ಲ. ನಮ್ಮನ್ನು ಸದಾ\nಪ್ರೀತಿಸುವ, ನಿರಂತರ ನಮ್ಮ ಒಳಗೆ-ಹೊರಗೆ ತುಂಬಿ ಸದಾ ರಕ್ಷಿಸುವ ಶಕ್ತಿ ಭಗವಂತ. ಪ್ರತಿಯೊಬ್ಬರನ್ನೂ\nಅವರವರ ಯೋಗ್ಯತೆಗೆ ತಕ್ಕಂತೆ ಬೆಳೆಸುವ, ತಪ್ಪು ಮಾಡಿದಾಗ ಕೇವಲ ತಿದ್ದುವುದಕ್ಕೋಸ್ಕರ ಶಿಕ್ಷೆ ಕೊಟ್ಟು ದಾರಿ\nತೋರುವ, ಸದಾ ಕಾರುಣ್ಯದಿಂದ ಮೇಲೆತ್ತುವ 'ಸುಹೃತ್‌' ಆ ಭಗವಂತ. ಇಂತಹ ಕರುಣಾಳು ಇನ್ನೊಬ್ಬ ನಿಲ್ಲ\nಎನ್ನುವ ಜ್ಞಾನ ಧ್ಯಾನದಲ್ಲಿ ಬಹಳ ಮುಖ್ಯ. ಈ ವಿಚಾರವನ್ನು ತಿಳಿದು ಅನುಸರಿಸಿದವ ಜ್ಞಾನಾನಂದದ\nಪರಾಕಾಷ್ಠೆಯಾದ ಮೋಕ್ಷವನ್ನುಪಡೆಯುತ್ತಾನೆ ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.\n\nಇತಿ ಪಂಚಮೋ*$ಧ್ಯಾಯಃ\nಐದನೆಯ ಅಧ್ಯಾಯ ಮುಗಿಯಿತು.\n\nಅಧ್ಯಾಯ ಆರು\n\nಹಿಂದಿನ ಅಧ್ಯಾಯದಲ್ಲಿ ಮುಖ್ಯವಾಗಿ ಭಗವಂತನ ಉಪಾಸನೆಯ ಸಾಧನೆಯನ್ನು ವಿವರಿಸಿದ ಕೃಷ್ಣ, ಈಗ ಆರನೇ\nಅಧ್ಯಾಯದಲ್ಲಿ ಧ್ಯಾನಯೋಗ ಮತ್ತು ಧ್ಯಾನಸಮಾಧಿಯನ್ನು ತಳಸ್ಪರ್ಶಿಯಾಗಿ ವಿವರಿಸುತ್ತಾನೆ.\n\nಭಗವಾನುವಾಚ ।\nಅನಾಶ್ರಿತಃ ಕರ್ಮಫಲಂ ಕಾರ್ಯಂ ಕರ್ಮ ಕರೋತಿ ಯಃ |\nಸ ಸಂನ್ಯಾಸೀ ಚಯೋಗೀಚನ ನಿರಗ್ನಿ ರ್ನ ಚಾಕ್ರಿಯಃ ॥೧॥\n\nಭಗವಾನ್‌ ಉವಾಚ- ಭಗವಂತ ಹೇಳಿದನು:\n\nಅನಾಶ್ರಿತಃ ಕರ್ಮಫಲಮ್‌ ಕಾರ್ಯಮ್‌ ಕರ್ಮ ಕರೋತಿ ಯಃ ।\n\nಸಃ ಸಂನ್ಯಾಸೀ ಚ ಯೋಗೀ ಚ ನ ನಿಃ ಅಗ್ನಿಃ ನ ಚ ಅಕ್ರಿಯಃ -ಕರ್ಮದ ಫಲ ನ್ಯಾಸ ಮಾಡಿ, ಕರ್ತವ್ಯವನ್ನು\nಮಾಡುತ್ತಿರುವವನೇ ನಿಜವಾದ ಸಂನ್ಯಾಸಿ ಮತ್ತು ನಿಜವಾದ ಯೋಗಿ. ಬೆಂಕಿಯಲ್ಲಿ ಹೋಮಿಸದೇ ಇರುವವನಲ್ಲ,\nಕರ್ಮವನ್ನು ತೊರೆದವನೂ ಅಲ್ಲ.\n\nಸಾಮಾನ್ಯವಾಗಿ ನಾವು ಕರ್ಮಯೋಗಿಗಳು ಬೇರೆ ಮತ್ತು ಸಂನ್ಯಾಸಿಗಳು ಬೇರೆ ಎಂದು ಎರಡು ಗುಂಪು\nಮಾಡುತ್ತೇವೆ. ಇಲ್ಲಿ ಕೃಷ್ಣ ಯಾರು ಸಂನ್ಯಾಸಿಗಳು, ಯಾರು ಕರ್ಮಯೋಗಿಗಳು ಎನ್ನುವ ಲೋಕದ ಕಲ್ಪನೆಗಿಂತ\nಭಿನ್ನವಾದ ವಿವರವನ್ನು ಈ ಶ್ಲೋಕದಲ್ಲಿ ನಮ್ಮ ಮುಂದಿಟ್ಟಿದ್ದಾನೆ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಅನಾಶ್ರಿತಃ ಕರ್ಮಫಲಂ”\nಎಂದು. ನಾವು ಸಾಮಾನ್ಯವಾಗಿ ಕರ್ಮತ್ಯಾಗ ಮಾಡಿದವರು ಸಂನ್ಯಾಸಿಗಳು, ಕರ್ಮ ಮಾಡುವವರು\nಗೃಹಸ್ಥರೆಂದು ಭಾವಿಸುತ್ತೇವೆ. ಆದರೆ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ ಪ್ರತಿಯೊಬ್ಬರೂ ಕರ್ಮಯೋಗಿಗಳಾಗಬೇಕು ಮತ್ತು\nಪ್ರತಿಯೊಬ್ಬರೂ ಸಂನ್ಯಾಸಿಗಳಾಗಬೇಕು ಎಂದು. ಇದು ಒಂದನ್ನು ಬಿಟ್ಟು ಒಂದು ಇರತಕ್ಕಂತದ್ದಲ್ಲ. ಸಂನ್ಯಾಸಿ\nಎಂದರೆ ನಾವು ಮಾಡಿದ್ದನ್ನೆಲ್ಲಾ ಭಗವಂತನಿಗೆ ಅರ್ಪಿಸುವುದೇ ಹೊರತು ಏನೂ ಮಾಡದೇ ಇರುವುದಲ್ಲ.\nಸಮಸ್ತ(ಸಂ) ಕರ್ಮವನ್ನು ಭಗವಂತನಿಗೆ ಅರ್ಪಿಸುವುದು 'ಸಂ-ನ್ಯಾಸ'. ಇಲ್ಲಿ ಬಹಳ ಮುಖ್ಯವಾದ ವಿಷಯ\nಎಂದರೆ ಕರ್ಮದ ಫಲದ ಬಯಕೆಯನ್ನು ಸಂಪೂರ್ಣನಾದ ಭಗವಂತನ ಹೃದಯದಲ್ಲಿ ನೆಲೆಗೊಳಿಸುವುದು.\nಸಂನ್ಯಾಸ ಎಂದರೆ ತನ್ನ ಕುಟುಂಬವನ್ನು ತೊರೆದು ಕಾಡಿಗೆ ಹೋಗುವುದಲ್ಲ. ಕರ್ಮಯೋಗ ಮಾಡಲೇ ಬೇಕು.\n“ಕಾರ್ಯಂ ಕರ್ಮ ಕರೋತಿ ಯಃ” ಯಾರ್ಯಾರಿಗೆ ಯಾವುದ್ಯಾವುದು ಕಾರ್ಯವೋ ಅವರವರು ಅದನ್ನದನ್ನು\nಮಾಡಲೇಬೇಕು. ಈ ಕಾರಣಕ್ಕಾಗಿ ಸಂನ್ಯಾಸ ಮತ್ತು ಕರ್ಮಯೋಗ ಎರಡೂ ಒಟ್ಟೊಟ್ಟಿಗಿರುವುದು. ನಿಜವಾದ\nಸಂನ್ಯಾಸಿ ಕರ್ಮಯೋಗಿಯಾಗಿರುತ್ತಾನೆ, ಮತ್ತು ನಿಜವಾದ ಕರ್ಮಯೋಗಿ ಸಂನ್ಯಾಸಿಯಾಗಿರುತ್ತಾನೆ. ಇದಲ್ಲದೆ\nನಾವು ತಿಳಿದಂತೆ ಕೇವಲ ಅಗ್ನಿಯನ್ನು ತ್ಯಾಗ ಮಾಡಿದವರು, ಕರ್ಮವನ್ನು ತ್ಯಾಗ ಮಾಡಿದವರು ಸಂನ್ಯಾಸಿಗಳು\nಅಥವಾ ಯೋಗಿಗಳಲ್ಲ.\n\nಸಂನ್ಯಾಸಿ ಎಂದೂ ನಿಷ್ಕ್ರೀಯ ಅಲ್ಲ. ಪ್ರತಿಯೊಬ್ಬರಿಗೂ ಅವರದ್ದೇ ಆದ ಕ್ರಿಯೆ ಇರುತ್ತದೆ. ಬ್ರಹ್ಮಚಾರಿಯಾದವನು\nಅಧ್ಯಯನ, ಗುರುಕುಲವಾಸ, ಗುರು ಶುಶ್ರೂಷೆ, ಇತ್ಯಾದಿ ಕಾರ್ಯ ಮಾಡಿದರೆ, ಗ್ರಹಸ್ಥ ಅತಿಥಿ ಸತ್ಕಾರ,\nಸಂಸಾರ ಪಾಲನೆ ಇತ್ಯಾದಿ ಕಾರ್ಯವನ್ನು ಮಾಡುತ್ತಾನೆ. ಹೀಗಾಗಿ ಎಲ್ಲರಿಗೂ ಕರ್ಮವಿದೆ.\n\nಯಂ ಸಂನ್ಯಾಸಮಿತಿ ಪ್ರಾಹುರ್ಯೋಗಂ ತಂ ವಿದ್ಧಿ ಪಾಂಡವ |\nನಹ್ಯಸಂನ್ಯಸ್ತಸಂಕಲ್ಪೋ ಯೋಗೀ ಭವತಿ ಕಶ್ಚನ ॥೨॥\n\nಯಮ್‌ ಸಂನ್ಯಾಸಮ್‌ ಇತಿ ಪ್ರಾಹುಃ ಯೋಗಮ್‌ ತಮ್‌ ವಿದ್ಧಿ ಪಾಂಡವ ।\n\nನ ಹಿ ಅಸಂನ್ಯಸ್ತ ಸಂಕಲ್ಪಃ",
  "6.1": "ಅಧ್ಯಾಯ ಆರು\n\nಹಿಂದಿನ ಅಧ್ಯಾಯದಲ್ಲಿ ಮುಖ್ಯವಾಗಿ ಭಗವಂತನ ಉಪಾಸನೆಯ ಸಾಧನೆಯನ್ನು ವಿವರಿಸಿದ ಕೃಷ್ಣ, ಈಗ ಆರನೇ\nಅಧ್ಯಾಯದಲ್ಲಿ ಧ್ಯಾನಯೋಗ ಮತ್ತು ಧ್ಯಾನಸಮಾಧಿಯನ್ನು ತಳಸ್ಪರ್ಶಿಯಾಗಿ ವಿವರಿಸುತ್ತಾನೆ.\n\nಭಗವಾನುವಾಚ ।\nಅನಾಶ್ರಿತಃ ಕರ್ಮಫಲಂ ಕಾರ್ಯಂ ಕರ್ಮ ಕರೋತಿ ಯಃ |\nಸ ಸಂನ್ಯಾಸೀ ಚಯೋಗೀಚನ ನಿರಗ್ನಿ ರ್ನ ಚಾಕ್ರಿಯಃ ॥೧॥\n\nಭಗವಾನ್‌ ಉವಾಚ- ಭಗವಂತ ಹೇಳಿದನು:\n\nಅನಾಶ್ರಿತಃ ಕರ್ಮಫಲಮ್‌ ಕಾರ್ಯಮ್‌ ಕರ್ಮ ಕರೋತಿ ಯಃ ।\n\nಸಃ ಸಂನ್ಯಾಸೀ ಚ ಯೋಗೀ ಚ ನ ನಿಃ ಅಗ್ನಿಃ ನ ಚ ಅಕ್ರಿಯಃ -ಕರ್ಮದ ಫಲ ನ್ಯಾಸ ಮಾಡಿ, ಕರ್ತವ್ಯವನ್ನು\nಮಾಡುತ್ತಿರುವವನೇ ನಿಜವಾದ ಸಂನ್ಯಾಸಿ ಮತ್ತು ನಿಜವಾದ ಯೋಗಿ. ಬೆಂಕಿಯಲ್ಲಿ ಹೋಮಿಸದೇ ಇರುವವನಲ್ಲ,\nಕರ್ಮವನ್ನು ತೊರೆದವನೂ ಅಲ್ಲ.\n\nಸಾಮಾನ್ಯವಾಗಿ ನಾವು ಕರ್ಮಯೋಗಿಗಳು ಬೇರೆ ಮತ್ತು ಸಂನ್ಯಾಸಿಗಳು ಬೇರೆ ಎಂದು ಎರಡು ಗುಂಪು\nಮಾಡುತ್ತೇವೆ. ಇಲ್ಲಿ ಕೃಷ್ಣ ಯಾರು ಸಂನ್ಯಾಸಿಗಳು, ಯಾರು ಕರ್ಮಯೋಗಿಗಳು ಎನ್ನುವ ಲೋಕದ ಕಲ್ಪನೆಗಿಂತ\nಭಿನ್ನವಾದ ವಿವರವನ್ನು ಈ ಶ್ಲೋಕದಲ್ಲಿ ನಮ್ಮ ಮುಂದಿಟ್ಟಿದ್ದಾನೆ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಅನಾಶ್ರಿತಃ ಕರ್ಮಫಲಂ”\nಎಂದು. ನಾವು ಸಾಮಾನ್ಯವಾಗಿ ಕರ್ಮತ್ಯಾಗ ಮಾಡಿದವರು ಸಂನ್ಯಾಸಿಗಳು, ಕರ್ಮ ಮಾಡುವವರು\nಗೃಹಸ್ಥರೆಂದು ಭಾವಿಸುತ್ತೇವೆ. ಆದರೆ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ ಪ್ರತಿಯೊಬ್ಬರೂ ಕರ್ಮಯೋಗಿಗಳಾಗಬೇಕು ಮತ್ತು\nಪ್ರತಿಯೊಬ್ಬರೂ ಸಂನ್ಯಾಸಿಗಳಾಗಬೇಕು ಎಂದು. ಇದು ಒಂದನ್ನು ಬಿಟ್ಟು ಒಂದು ಇರತಕ್ಕಂತದ್ದಲ್ಲ. ಸಂನ್ಯಾಸಿ\nಎಂದರೆ ನಾವು ಮಾಡಿದ್ದನ್ನೆಲ್ಲಾ ಭಗವಂತನಿಗೆ ಅರ್ಪಿಸುವುದೇ ಹೊರತು ಏನೂ ಮಾಡದೇ ಇರುವುದಲ್ಲ.\nಸಮಸ್ತ(ಸಂ) ಕರ್ಮವನ್ನು ಭಗವಂತನಿಗೆ ಅರ್ಪಿಸುವುದು 'ಸಂ-ನ್ಯಾಸ'. ಇಲ್ಲಿ ಬಹಳ ಮುಖ್ಯವಾದ ವಿಷಯ\nಎಂದರೆ ಕರ್ಮದ ಫಲದ ಬಯಕೆಯನ್ನು ಸಂಪೂರ್ಣನಾದ ಭಗವಂತನ ಹೃದಯದಲ್ಲಿ ನೆಲೆಗೊಳಿಸುವುದು.\nಸಂನ್ಯಾಸ ಎಂದರೆ ತನ್ನ ಕುಟುಂಬವನ್ನು ತೊರೆದು ಕಾಡಿಗೆ ಹೋಗುವುದಲ್ಲ. ಕರ್ಮಯೋಗ ಮಾಡಲೇ ಬೇಕು.\n“ಕಾರ್ಯಂ ಕರ್ಮ ಕರೋತಿ ಯಃ” ಯಾರ್ಯಾರಿಗೆ ಯಾವುದ್ಯಾವುದು ಕಾರ್ಯವೋ ಅವರವರು ಅದನ್ನದನ್ನು\nಮಾಡಲೇಬೇಕು. ಈ ಕಾರಣಕ್ಕಾಗಿ ಸಂನ್ಯಾಸ ಮತ್ತು ಕರ್ಮಯೋಗ ಎರಡೂ ಒಟ್ಟೊಟ್ಟಿಗಿರುವುದು. ನಿಜವಾದ\nಸಂನ್ಯಾಸಿ ಕರ್ಮಯೋಗಿಯಾಗಿರುತ್ತಾನೆ, ಮತ್ತು ನಿಜವಾದ ಕರ್ಮಯೋಗಿ ಸಂನ್ಯಾಸಿಯಾಗಿರುತ್ತಾನೆ. ಇದಲ್ಲದೆ\nನಾವು ತಿಳಿದಂತೆ ಕೇವಲ ಅಗ್ನಿಯನ್ನು ತ್ಯಾಗ ಮಾಡಿದವರು, ಕರ್ಮವನ್ನು ತ್ಯಾಗ ಮಾಡಿದವರು ಸಂನ್ಯಾಸಿಗಳು\nಅಥವಾ ಯೋಗಿಗಳಲ್ಲ.\n\nಸಂನ್ಯಾಸಿ ಎಂದೂ ನಿಷ್ಕ್ರೀಯ ಅಲ್ಲ. ಪ್ರತಿಯೊಬ್ಬರಿಗೂ ಅವರದ್ದೇ ಆದ ಕ್ರಿಯೆ ಇರುತ್ತದೆ. ಬ್ರಹ್ಮಚಾರಿಯಾದವನು\nಅಧ್ಯಯನ, ಗುರುಕುಲವಾಸ, ಗುರು ಶುಶ್ರೂಷೆ, ಇತ್ಯಾದಿ ಕಾರ್ಯ ಮಾಡಿದರೆ, ಗ್ರಹಸ್ಥ ಅತಿಥಿ ಸತ್ಕಾರ,\nಸಂಸಾರ ಪಾಲನೆ ಇತ್ಯಾದಿ ಕಾರ್ಯವನ್ನು ಮಾಡುತ್ತಾನೆ. ಹೀಗಾಗಿ ಎಲ್ಲರಿಗೂ ಕರ್ಮವಿದೆ.\n\nಯಂ ಸಂನ್ಯಾಸಮಿತಿ ಪ್ರಾಹುರ್ಯೋಗಂ ತಂ ವಿದ್ಧಿ ಪಾಂಡವ |\nನಹ್ಯಸಂನ್ಯಸ್ತಸಂಕಲ್ಪೋ ಯೋಗೀ ಭವತಿ ಕಶ್ಚನ ॥೨॥",
  "6.2": "ಯಮ್‌ ಸಂನ್ಯಾಸಮ್‌ ಇತಿ ಪ್ರಾಹುಃ ಯೋಗಮ್‌ ತಮ್‌ ವಿದ್ಧಿ ಪಾಂಡವ ।\n\nನ ಹಿ ಅಸಂನ್ಯಸ್ತ ಸಂಕಲ್ಪಃ ಯೋಗೀ ಭವತಿ ಕಶ್ಚನ-ಯಾವುದನ್ನು ಸಂನ್ಯಾಸವೆನ್ನುವರೋ ಅದನ್ನೇ\nಯೋಗವೆಂದು ತಿಳಿ ಪಾಂಡವಾ. ಬಯಕೆಗಳ 'ಸಂನ್ಯಾಸ' ಮಾಡದ ಯಾವನೂ ಮರ್ಮವರಿತ\nಕರ್ಮಯೋಗಿಯಾಗಲಾರ.\n\nಸಂನ್ಯಾಸ ಕೂಡಾ ಒಂದು ಯೋಗ. ಕರ್ಮ ಫಲತ್ಯಾಗ ಕೂಡಾ ಕರ್ಮ ಮಾಡತಕ್ಕ ಕರ್ಮಯೋಗಿಯ ಯೋಗದ\nಒಂದು ಮುಖ. ಎಲ್ಲವನ್ನೂ ಭಗವಂತನಿಗೆ ಅರ್ಪಣೆ ಮಾಡಿ ಫಲಕಾಮನೆ ಇಲ್ಲದೆ ಭಗವದ್‌ ಪೂಜಾ ದೃಷ್ಟಿಯಿಂದ\nಮಾಡುವಂತಹ ಕ್ರಿಯೆ ಸಾತ್ವಿಕರ ಸಾಧನೆ. ಸಂನ್ಯಾಸ ಎಂದರೆ ಕಾಮ-ಸಂಕಲ್ಪವನ್ನು ಭಗವಂತನಲ್ಲಿ\nಅರ್ಪಿಸುವುದು. ಕಾಮ ಅಂದರೆ “ಮಾಡಬೇಕು' ಎಂದು ಬಯಸುವುದು, ಸಂಕಲ್ಪ ಎಂದರೆ \"ಮಾಡುತ್ತೇನೆ' ಎಂದು\nನಿರ್ಧರಿಸುವುದು. ಕಾಮಸಂಕಲ್ಪ ವರ್ಜಿತ-ಸಂನ್ಯಾಸ. ಇಲ್ಲಿ ಕೃಷ್ಣ ವಿವರಿಸುತ್ತಿರುವುದು\nಆಶ್ರಮಕ್ಕೆ(ಸಂನ್ಯಾಸಾಶ್ರಮ) ಸಂಬಂಧಪಟ್ಟ ವಿಚಾರವಲ್ಲ. ಇದು ಸಾಧನೆಗೆ ಸಂಬಂಧಪಟ್ಟ ವಿಚಾರ. ಸಾಧನೆಯ\nಮುಖದಲ್ಲಿ ಯೋಗಿಗಳು ಸಂನ್ಯಾಸಿಗಳಾಗಬೇಕು ಮತ್ತು ಸಂನ್ಯಾಸಿಗಳು ಯೋಗಿಗಳಾಗಬೇಕು ಇದು ಕೃಷ್ಣನ\n\nಸಂದೇಶ.\n\nನಾವು ಸಾಧನೆ ಮಾಡುವಾಗ ಕರ್ಮವೂ ಇರಬೇಕು, ಫಲನ್ಯಾಸವೂ ಇರಬೇಕು. ಹೀಗಿರುವಾಗ ಎಲ್ಲರೂ\nಮಾಡಬೇಕಾದ ಕರ್ಮ ಎಂದು ಯಾವುದಾದರೂ ಕರ್ಮವನ್ನು ಪರಿಗಣನೆ ಮಾಡಿದ್ದಾರೋ ? ಸಾಧಕನ\nಸಾಮಾಜಿಕ ಕರ್ತವ್ಯ ಯಾವುದು? ಸಮಾಜದೊಂದಿಗೆ ಒಬ್ಬ ಸಾಧಕ ಹೇಗೆ ಸ್ಪಂದಿಸಬೇಕು? ಕರ್ಮದ ಕೊನೆ\nಎಂದು? ಸಾಧನೆಗೂ ಕರ್ಮಕ್ಕೂ ಇರುವ ಹೊಂದಿಕೆ ಏನು? ಅದು ಹೇಗೆ ಸಾಧನೆಗೆ ಪೂರಕ? ಈ ಎಲ್ಲಾ\nಪ್ರಶ್ನೆಗಳಿಗೆ ಕೃಷ್ಣ ಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ಉತ್ತರ ಕೊಡುತ್ತಾನೆ.\n",
  "6.3": "ಆರುರುಕ್ಷೋಃ ಮುನೇಃ ಯೋಗಮ್‌ ಕರ್ಮ ಕಾರಣಮ್‌ ಉಚ್ಯತೇ |\n\nಯೋಗ ಆರೂಢಸ್ಯ ತಸ್ಯ ಏವ ಶಮಃ ಕಾರಣಮ್‌ ಉಚ್ಯತೇ -ಸಾಧನೆಯ ಮೆಟ್ಟ ಲೇರುವವನಿಗೆ ಗುರಿ ಮುಟ್ಟ ಲು\nಕರ್ಮಯೋಗ[ಹಲವು ಬಗೆಯ ಜನಸೇವೆ]ಕಾರಣವೆನಿಸುತ್ತದೆ. ಅವನೇ ಗುರಿ ಸೇರಿದಾಗ ಭಗವದ್‌ ಸಮಾಧಿ\n[ಜನ ಸೇವೆಯಿಂದ ವಿರಾಮ ಮತ್ತು ಭಗವಂತನಲ್ಲಿ ಧ್ಯಾನ ನಿಷ್ಠೆ] ಸುಖದ ಹೆಚ್ಚಳಕ್ಕೆ ಕಾರಣವೆನಿಸುತ್ತದೆ.\n\nಈ ಶ್ಲೋಕಕ್ಕೆ ಎರಡು ಆಯಾಮವಿದೆ. ಒಬ್ಬ ಸಾಧಕ ತನ್ನ ನಿತ್ಯಕರ್ಮವನ್ನು ಎಲ್ಲಿಯ ತನಕ ಮಾಡಬೇಕು ಮತ್ತು\nಎಲ್ಲಿಂದ ಬಿಡಬಹುದು ಎನ್ನುವುದು ಒಂದು ಆಯಾಮವಾದರೆ, ಇನ್ನೊಂದು ಸಾಮಾಜಿಕವಾಗಿ ಒಬ್ಬ ಸಾಧಕನ\nಕರ್ತವ್ಯವೇನು ಎನ್ನುವುದನ್ನು ಈ ಶ್ಲೋಕ ವಿವರಿಸುತ್ತದೆ.\n\nಇನ್ನೂ ಸಿದ್ಧಿ ಪಡೆಯದ, ಸಾಧನೆಯ ಹಾದಿಯಲ್ಲಿರುವ ಒಬ್ಬ ಸಾಧಕ ಆ ಸ್ಥಿತಿಯಲ್ಲಿ ಎಲ್ಲಾ ವಿಹಿತಕರ್ಮವನ್ನು\nಮಾಡುತ್ತಿರಬೇಕು, ಯಾವುದನ್ನೂ ಬಿಡುವಂತಿಲ್ಲ. ಸಿದ್ಧನಾದ ಮೇಲೆ ಆತ ಸಮಾಧಿ ಸ್ಥಿತಿಯಲ್ಲಿ ಭಗವಂತನನ್ನು\nಒಳಗಿನಿಂದ ಕಾಣಬಲ್ಲ. ಆ ಸ್ಥಿತಿಯಲ್ಲಿ ಆತನಿಗೆ ಉಳಿದ ಕರ್ಮಗಳಿಗಿಂತ ಅಂತರಂಗದಲ್ಲಿ ಭಗವಂತನನ್ನು\nಕಾಣುವ ಕರ್ಮ ಮುಖ್ಯವಾಗುತ್ತದೆ. ಒಬ್ಬ ಅಪರೋಕ್ಚ ಜ್ಞಾನ ಬಂದವ ಸದಾ ಸಮಾಧಿ ಸ್ಥಿತಿಯಲ್ಲಿ ಇರಲು\nಸಾಧ್ಯವಿಲ್ಲ. ಅವನು ಹೊರ ಪ್ರಪಂಚಕ್ಕೆ ಬರಲೇ ಬೇಕು. ಆಗ ಅವನ ಮುಖ್ಯ ಕರ್ಮವೆಂದರೆ ಶಾಸ್ತ್ರ ಶ್ರವಣ,\nಮಂತ್ರ ಜಪ, ಪ್ರವಚನ ಇತ್ಯಾದಿ. ಆದ್ದರಿಂದ ವಿಹಿತಕರ್ಮಗಳ ವಿಧಿನಿಷೇಧ ಬದ್ಧತೆ ಅಪರೋಕ್ಷ ಜ್ಞಾನದವರೆಗೆ\nಮಾತ್ರ. ಉದಾಹರಣೆಗೆ ಒಬ್ಬ ಅಪರೋಕ್ಷ ಜ್ಞಾನಿ ಧ್ಯಾನಕ್ಕೆ ಕುಳಿತಿದ್ದಾನೆ. ಆತ ತನ್ನ ಅಂತರಂಗದಲ್ಲಿ\nಭಗವಂತನನ್ನು ಕಾಣುತ್ತಿದ್ದಾನೆ ಮತ್ತು ಆ ಆನಂದದಲ್ಲಿ ಮುಳುಗಿದ್ದಾನೆ. ಅದು ಬೆಳಗಿನಜಾವ-ಸೂರ್ಯೋದಯದ\nಕಾಲ. ಸ್ನಾನ ಮಾಡಿ ಸಂಧ್ಯಾವಂದನೆ ಮಾಡುವ ಸಮಯದಲ್ಲಿ ಈತ ಧ್ಯಾನದಲ್ಲಿ ಕುಳಿತಿದ್ದಾನಲ್ಲ ಎಂದು ನಾವು\nಅವನನ್ನು ಎಬ್ಬಿಸುವುದು ತಪ್ಪು. ಆತ ಸಂಧ್ಯಾವಂದನೆ ಮಾಡದಿದ್ದರೆ ಯಾವ ಕರ್ಮ ಲೇಪವೂ ಆಗುವುದಿಲ್ಲ.\nಏಕೆಂದರೆ ಸಂಧ್ಯಾವಂದನೆ ಮಾಡುವುದು ಭಗವಂತನ ದರ್ಶನಕ್ಕಾಗಿ. ಆದರೆ ಆತ ಆಗಲೇ ಭಗವಂತನ ದರ್ಶನ\nಪಡೆಯುತ್ತಿದ್ದಾನೆ. ಹೀಗೆ ಅಪರೋಕ್ಷ ಜ್ಞಾನಿಗೆ ಕರ್ಮದ ಬದ್ಧತೆ ಇಲ್ಲ. ಸಮಾಧಿಸ್ಥಿತಿಯಿಂದ ಹೊರಬಂದ ಮೇಲೆ\nಇರತಕ್ಕ ಕರ್ತವ್ಯ ಎಂದರೆ ಭಗವಂತನ ಗುಣಗಾನ, ಪ್ರವಚನ, ಅಧ್ಯಯನ, ಜಪ ಇತ್ಯಾದಿ.\n\nಈ ಶ್ಲೋಕದ ಇನ್ನೊಂದು ಆಯಾಮವನ್ನು ಬಹಳ ಸುಂದರವಾಗಿ ಮಧ್ವಾಚಾರ್ಯರು ತಮ್ಮ\nಗೀತಾತಾತ್ಪರ್ಯದಲ್ಲಿ ವಿವರಿಸಿದ್ದಾರೆ. ಇದು ಮುಖ್ಯವಾಗಿ ಒಬ್ಬ ಸಾಧಕನ ಸಾಮಾಜಿಕ ನಡೆ ಹೇಗಿರಬೇಕು\nಎನ್ನುವುದನ್ನು ವಿವರಿಸುತ್ತದೆ. ಕರ್ಮ ಎನ್ನುವುದಕ್ಕೆ ಆಚಾರ್ಯರು ಒಂದು ಅಪೂರ್ವ ಅರ್ಥವನ್ನು ಕೊಟ್ಟಿದ್ದಾರೆ.\nಕರ್ಮ ಅಂದರೆ ಕರಮ. ಕರ ಅಂದರೆ ಕಂದಾಯ(Duty)). ಯಾವುದನ್ನು ಕಂದಾಯವೆಂದು ತಿಳಿದು ನಾವು\nಮಾಡಬೇಕೋ ಅದು “ಕರ-ಮ'. ನಾವು ಭಗವಂತನ ರಾಜ್ಯದಲ್ಲಿನ ಪ್ರಜೆಗಳು. ಅದಕ್ಕೋಸ್ಕರ ಅವನಿಗೆ ನಾವು\nಕೊಡುವ ಕರ-ಕರ್ಮ. ಯಾವುದೋ ಅಭಿಲಾಷೆಯಿಂದ ದೇವಸ್ಥಾನದಲ್ಲಿ ನಾವು ಕಾಣಿಕೆ ಹಾಕುವುದು ನಿಜವಾದ\nಕಂದಾಯವಲ್ಲ. ಅದನ್ನು ಭಗವಂತ ಬಯಸುವುದೂ ಇಲ್ಲ. ಭಗವಂತ ನಮ್ಮಿಂದ ಬಯಸುವ ಕರ್ಮ\nಕಷ್ಟದಲ್ಲಿರುವವರ ಶುಶ್ರೂಷೆ. ಒಬ್ಬ ಸಾಧಕ ಅಪರೋಕ್ಷ ಸಾಧಕನಾಗುವ ತನಕ ಅವನ ಸಾಧನೆಯಲ್ಲಿ ಇದು\nಒಂದು ಮುಖ್ಯ ಸಾಧನೆ. ಸಮಸ್ತ ಜೀವಜಾತದ ಮೇಲೆ ಅನುಕಂಪ, ಸೇವಾ ಮನೋವೃತ್ತಿ ಬಹಳ ಮುಖ್ಯ.\nಯೋಗಶಾಸ್ತ್ರದಲ್ಲಿ ಕೂಡಾ ಇದನ್ನೇ ಹೇಳುತ್ತಾರೆ. ಮೈತ್ರಿ, ಕರುಣಾ, ಮುದಿತ ಮತ್ತು ಉಪೇಕ್ಷ ಎನ್ನುವ ನಾಲ್ಕು\n\nಮನೋವೃತ್ತಿ ಒಬ್ಬ ಸಾಧಕನಲ್ಲಿರಬೇಕು. ಮೈತ್ರಿ ಎಂದರೆ ಸಜ್ಜನರ ಸಹವಾಸ. ಎಲ್ಲಿ ಒಳ್ಳೆಯತನವಿದೆ ಅವರ\nಸ್ನೆ ಹ. ದುಃಖವನ್ನು ಕಂಡಾಗ ಅಲ್ಲಿ ಕರುಣೆ ಹಾಗೂ ನೆರವು-ಕರುಣಾ. ಇನ್ನೊ ಬ್ಬರ ಉದ್ಧಾರ ನೋಡಿ\nಸಂತೋಷಪಡುವುದು ಮುದಿತ. ದುಷ್ಟರಿಂದ ದೂರವಿರುವುದು ಉಪೇಕ್ಷ. ಕೆಟ್ಟವರೊಂದಿಗೆ ಜಗಳ ಬೇಡ ಆದರೆ\nಅವರ ಒಡನಾಟದಿಂದ ಯಾವುದೇ ದ್ವೇಷವಿಲ್ಲದೆ ದೂರವಿರುವುದು ಉಪೇಕ್ಷ. ಹೀಗೆ ಸಾಧಕನ ಜೀವನದಲ್ಲಿ ಇದು\nಮಹತ್ತರವಾದ ಸಾಮಾಜಿಕ ಕರ್ತವ್ಯ. ಒಬ್ಬ ಸಿದ್ಧನಾದವ(ಯೋಗಾರೂಢ) ಸದಾ ಅಂತರ್ಮುಖಿಯಾಗಿರುತ್ತಾನೆ.\nಅವನಿಗೆ ಈ ಸಾಮಾಜಿಕ ಬದ್ಧತೆ ಇಲ್ಲ(ಅವನಿಗೆ ಅದು ಸಾಧ್ಯವಾಗುವುದಿಲ್ಲ). ಅವನ ಆನಂದಾಭಿವೃದ್ಧಿಗೆ ಕಾರಣ\n'ಶಮಃ. ಅಂದರೆ ಸದಾ ಭಗವಂತನಲ್ಲೇ ಮನಸ್ಸನ್ನು ನೆಟ್ಟಿರುವುದು. ಅದರಿಂದ ವ್ಯತಿರಿಕ್ತವಾದ ಇನ್ನೊಂದು\nಕರ್ಮ ಅವನಿಗಿಲ್ಲ.\n\nಹೀಗೆ ಲೋಕಸೇವೆ ಎನ್ನುವುದು ಒಬ್ಬ ಸಾಧಕನ ಅವಿಭಾಜ್ಯ ಅಂಗವಾಗಬೇಕು ಎನ್ನುವುದನ್ನು ಕೃಷ್ಣ ಈ\nಶ್ಲೋಕದಲ್ಲಿ ಸ್ಪಷ್ಟವಾಗಿ ಹೇಳಿದ. ಯೋಗಾರೂಢನಿಗೆ ಯಾವ ಸಾಮಾಜಿಕ ಭದ್ಧತೆಯೂ ಇಲ್ಲ, ಅವನು\nಅಂತರಂಗದಲ್ಲಿ ಭಗವಂತನನ್ನು ಕಾಣುತ್ತಿರುತ್ತಾನೆ. ಎಂದು ಕೃಷ್ಣ ಹೇಳಿದಾಗ ನಮಗೆ ಒಂದು ಪ್ರಶ್ನೆ\nಮೂಡಬಹುದು. ಇಂತಹ ಅಪರೋಕ್ಷ ಜ್ಞಾನಿಗಳನ್ನು ಗುರುತಿಸುವುದು ಹೇಗೆ ಎಂದು. ಮುಂದಿನ ಶ್ಲೋಕ ಈ\n\nನಮ್ಮ ಪ್ರಶ್ನೆಗೆ ಉತ್ತರ ರೂಪದಲ್ಲಿದೆ.\n",
  "6.4": "ಯದಾ ಹಿ ನ ಇಂದ್ರಿಯ ಅರ್ಥೇಷು ನ ಕರ್ಮಸು ಅನುಷಜ್ಜತೇ ।\nಸರ್ವ ಸಂಕಲ್ಪ ಸಂನ್ಯಾಸೀ ಯೋಗಾರೂಢಃ ತದಾ ಉಚ್ಯತೇ -- ಎಲ್ಲಾ ಕರ್ಮದ ಹೊಣೆಯನ್ನೂ\nಭಗವಂತನಿಗರ್ಪಿಸಿ, ಇಂದ್ರಿಯ ವಿಷಯಗಳಲ್ಲಿ ಮತ್ತು ಕರ್ಮಗಳಲ್ಲಿ ಬಗೆಯ ನಂಟು ಕಳೆದುಕೊಂಡಾಗ\n\nಸಾಧನೆಯ ಗುರಿ ಸೇರಿದವನೆನಿಸುತ್ತಾನೆ.\n\nಅಪರೋಕ್ಷ ಜ್ಞಾನಿಯ ಲಕ್ಷಣವನ್ನು ಹೇಳುತ್ತಾ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಯದಾ ಹಿ ನ ಇಂದ್ರಿಯ ಅರ್ಥೇಷು ನ\nಕರ್ಮಸು ಅನುಷಜ್ವತೇ” ಎಂದು. ಅಂದರೆ ಅಪರೋಕ್ಷ ಜ್ಞಾನಿ ಇಂದ್ರಿಯಗಳನ್ನು ಸೆಳೆಯುವ ಸಂಗತಿಗಳಲ್ಲಿ\n(ಶಬ್ದ, ರೂಪ, ರಸ, ಗಂಧ, ಸ್ಪರ್ಶ, ಅಥವಾ ಯಾವ ವಿಷಯದಲ್ಲೂ ಅಂಟಿಕೊಂಡಿರುವುದಿಲ್ಲ. ಆತ ಕ್ರಿಯೆ\nಮಾಡುತ್ತಾನೆ ಆದರೆ ಅದಕ್ಕೆ ತನ್ನನ್ನು ಅಂಟಿಸಿಕೊಳ್ಳುವುದಿಲ್ಲ. ಸಾಧನೆಯ ಹಾದಿಯಲ್ಲಿರುವ ಸಾಧಕ ಕಷ್ಟಪಟ್ಟು\nಇಂದ್ರಿಯ ನಿಗ್ರಹ ಮಾಡಿದರೆ, ಅಪರೋಕ್ಷ ಜ್ಞಾನಿಗಳಿಗೆ ಇದು ಸಹಜ ಧರ್ಮವಾಗಿರುತ್ತದೆ. ಖುಗ್ವೇದದಲ್ಲಿ\nಹೇಳುವಂತೆ “ಜಗತ್ತಿನ ನಿಯಾಮಕ ನರಸಿಂಹ. ಅವನ ಬಯಕೆಯೇ ನನ್ನ ಬಯಕೆಯಾಗಲಿ. ಅವನ ಹೃದಯದಲ್ಲಿ\nಏನು ಬಯಕೆ ಇದೆ ಅದೇ ನನ್ನ ಭಾವನೆಯಾಗಲಿ. ಅದಕ್ಕೆ ವಿರುದ್ಧವಾದ ಸಂಕಲ್ಪ ನನಗೆ ಬಾರದೇ ಇರಲಿ”. ಈ\nರೀತಿ ಅಪರೋಕ್ಷಜ್ಞಾನಿ ಬಯಸುತ್ತಾನೆ. ಅವನು ಏನನ್ನೂ ಕೂಡಾ ಇಂದ್ರಿಯದ ಮೂಲಕ ಅನುಭವಿಸಬೇಕು\nಎಂದು ಬಯಸುವುದಿಲ್ಲ, ಪರಿತಪಿಸುವುದಿಲ್ಲ. ಇಂದ್ರಿಯದ ಮೂಲಕ ಬಂದ ಅನುಭವದಿಂದ ಪ್ರಭಾವಿತನಾಗಿ\n\nಅದಕ್ಕೆ ಅಂಟಿಕೊಳ್ಳುವುದೂ ಇಲ್ಲ. ಎಲ್ಲವನ್ನೂ ತಟಸ್ಥವಾಗಿ ನೋಡುತ್ತಿರುತ್ತಾನೆ. ನಾವು ಸಮುದ್ರದ ತಟದಲ್ಲಿ\nಕುಳಿತು ಸಮುದ್ರವನ್ನು ನೋಡುತ್ತಿದ್ದರೆ ಅಲ್ಲಿ ಅನೇಕ ರೀತಿಯ ಅಲೆಗಳಿರುತ್ತವೆ. ನಾವು ಆ ಅಲೆಗಳನ್ನು ನೋಡಿ\nಆನಂದಿಸುತ್ತಿರುತ್ತೇವೆ. ಅಲ್ಲಿ ಬರುವ ತೆರೆಗಳ ನಿಯಂತ್ರಣ ನಮ್ಮ ಕೈಯಲ್ಲಿಲ್ಲ. ಯಾವ ಅಲೆ ಹೇಗೆ ಬಂತೋ\nಹಾಗೇ ತಟಸ್ಥವಾಗಿ ಆಸ್ವಾದಿಸುವುದರಲ್ಲಿ ಆನಂದವಿದೆ. ಜೀವನ ಸಾಗರದಲ್ಲಿ ಕಷ್ಟ ಸುಖ ನೋವು ನಲಿವು\nಎಲ್ಲವೂ ಅಲೆಗಳಂತೆ ಬಂದು ಹೋಗುತ್ತಿರುತ್ತವೆ. ಅದರ ನಿಯಂತ್ರಣ ನಮ್ಮ ಕೈಯಲ್ಲಿಲ್ಲ. ಸಮುದ್ರದ ಅಲೆಯನ್ನು\nನೋಡಿ ಸಂತೋಷಪಟ್ಟಂತೆ ಈ ಜೀವನದ ಅಲೆಯನ್ನು ಸಹಜವಾಗಿ ನೋಡಿ ಸಂತೋಷಪಡುತ್ತಾ ಬಾಳುವುದೇ\nಅಪರೋಕ್ಷ ಜ್ಞಾನಿಯ ಲಕ್ಷಣ.\n\nಈ ಅಧ್ಯಾಯದಲ್ಲಿ ಕೃಷ್ಣ ಧ್ಯಾನದ ಸಂಪೂರ್ಣ ಪ್ರಕ್ರಿಯೆಯನ್ನು ಮುಂದೆ ವಿವರಿಸುತ್ತಾನೆ. ಅದಕ್ಕಾಗಿ ನಮ್ಮ\nಮನಸ್ಸನ್ನು ಹೇಗೆ ಸಜ್ಜುಗೊಳಿಸಬೇಕು, ನಾವು ಯೋಗಾರೂಢರಾಗಬೇಕಾದರೆ ಏನು ಮಾಡಬೇಕು ಎನ್ನುವುದರ\nಪ್ರಸ್ತಾವನೆ ಮುಂದಿನ ಶ್ಲೋಕ.\n\nಉದ್ಧರೇದಾತ್ಮನಾ$55ತ್ಮಾನಂ ನಾ*ತ್ಮಾನಮವಸಾದಯೇತ್‌ |\nಆತೆ ಟ್ಮವೆ ಹ್ಯಾತ್ಮನೋ ಬಂಧುರಾತೆ ಟ್ಮವೆ ರಿಪುರಾತ್ಮನಃ",
  "6.5": "ಉದ್ಧರೇತ್‌ ಆತ್ಮನಾ ಆತ್ಮಾನಮ್‌ ನ ಆತ್ಮಾನಮ್‌ ಅವಸಾದಯೇತ್‌ |\n\nಆತ್ಮಾ ಏವಹಿ ಆತ್ಮನಃ ಬಂಧುಃ ಆತ್ಮಾ ಏವ ರಿಪುಃ ಆತ್ಮನಃ -ಬಗೆಯ ಬಲದಿಂದ [ಭಗವಂತನ ಪ್ರಸಾದದಿಂದ]\nಜೀವವನ್ನು ಮೇಲೆತ್ತಬೇಕು; ಜೀವವನ್ನು ಜಂಜಡಗೊಳಿಸಬಾರದು. ಬಗೆಯೇ[ಭಗವಂತನೇ] ಜೀವದ ಗೆಳೆಯ;\nಬಗೆಯೇ[ಭಗವಂತನೇ]ಜೀವದ ಹಗೆಯು.\n\nಈ ಹಿಂದೆ ಹೇಳಿದಂತೆ ಆತ್ಮ ಎನ್ನುವ ಪದಕ್ಕೆ ಅನೇಕ ಅರ್ಥಗಳಿವೆ. ಆತ್ಮ ಎಂದರೆ ಶರೀರ, ಮನಸ್ಸು, ಜೀವ,\nಪರಮಾತ್ಮ. ಹೀಗೆ ಈ ಶ್ಲೋಕದಲ್ಲಿ ಬಂದಿರುವ ಆತ್ಮ ಶಬ್ದಕ್ಕೆ ಈ ಎಲ್ಲಾ ಅರ್ಥವನ್ನೂ ಜೋಡಿಸಿ ನೋಡಿದರೆ\nಅನೇಕ ವಿಚಾರ ಸ್ಪಷ್ಟವಾಗುತ್ತದೆ. “ಉದ್ಧರೇತ್‌ ಆತ್ಮನಾ ಆತ್ಮಾನಮ್‌ ನ ಆತ್ಮಾನಮ್‌ ಅವಸಾದಯೇತ್‌”\nಅಂದರೆ ನಮ್ಮ ಅಧಃಪಾತಕ್ಕೂ ಕಾರಣ ಮನಸ್ಸು. ನಮ್ಮ ಉದ್ಧಾರಕ್ಕೂ ಕಾರಣ ಮನಸ್ಸು. ಆದ್ದರಿಂದ\nಮನಸ್ಸಿನಿಂದ(ಆತ್ಮಾನಾ) ಜೀವದ(ಆತ್ಮಾನಂ) ಉದ್ಧಾರದ ದಾರಿಯನ್ನು ಹುಡುಕು ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಎಂದೂ\nಮನಸ್ಸನ್ನು ಕೆಳಕ್ಕೆ ಕಳುಹಿಸಬೇಡ. ಆತ್ಮದ(ಜೀವದ) ಅವಸಾನಕ್ಕೆ ಕಾರಣವಾಗುವಂತೆ ಮನಸ್ಸನ್ನು\nಸ್ವಚ್ಛಂದವಾಗಿ ಬಿಡಬೇಡ. ಅದನ್ನು ಮೇಲಕ್ಕೆ ಕೊಂಡು ಹೋಗು. ಮನಸ್ಸು ಕೆಳಗೆ ಹೋದರೆ ಅದು ನಮ್ಮನ್ನು\nಪಾತಾಳಕ್ಕೆ ತಳ್ಳಿ ಬಿಡುತ್ತದೆ. \"ಆ ಮನಸ್ಸನ್ನು ಎತ್ತರಕ್ಕೆ ಕಳಿಸು. ಎತ್ತರಕ್ಕೆ ಹೋದ ಮನಸ್ಸು ನಿನ್ನನ್ನು ಎತ್ತರಕ್ಕೆ\nಕೊಂಡೊಯ್ಯುತ್ತದೆ. ಮನಸ್ಸಿನಿಂದ ನಿನ್ನ ಜೀವ ಸ್ವರೂಪವನ್ನು ಉದ್ಧಾರ ಮಾಡಿಕೋ. ಜೀವಕ್ಕೆ ಮನಸ್ಸೇ ಬಂಧು,\nಮನಸ್ಸೇ ಶತ್ರು. ಆದ್ದರಿಂದ ಸಾಧನೆ ಮಾಡಬೇಕಾದರೆ ಮನಸ್ಸನ್ನು ಬಂಧುವಾಗಿ ಪರಿವರ್ತನೆ ಮಾಡಿಕೋ.\nಮನಸ್ಸು ನಿನ್ನ ಶತ್ರುವಾಗಿ ನಿಂತರೆ ನಿನ್ನ ಜೀವಮಾನದಲ್ಲೇ ಉದ್ಧಾರವಿಲ್ಲ. ಅದಕ್ಕಾಗಿ ಮೊದಲು ಬುದ್ಧಿಬಲದಿಂದ\n\nಮನಸ್ಸಿಗೆ ತರಬೇತಿ ಕೊಟ್ಟು ಅದನ್ನು ಗೆಲ್ಲಬೇಕು' ಎನ್ನುವುದು ಕೃಷ್ಣನ ಸಂದೇಶ. ಮನಸ್ಸನ್ನು ಗೆದ್ದರೆ ಎಲ್ಲವೂ\nಪ್ರಶಾಂತ, ಯಾವ ಗೊಂದಲವೂ ಇಲ್ಲ. ಇದು ಧ್ಯಾನಕ್ಕೆ ಬೇಕಾದ ಪೂರ್ವ ಸ್ಥಿತಿ.\n\nಕೃಷ್ಣನ ಈ ಸಂದೇಶ ಕೇಳಿದಾಗ ನಮಗೆ ಒಂದು ಪ್ರಶ್ನೆ ಎದುರಾಗುತ್ತದೆ. ಈ ಹಿಂದೆ ಕೃಷ್ಣನೇ ಹೇಳಿದಂತೆ\nಯಾವುದೂ ನಮ್ಮ ಕೈಯಲ್ಲಿಲ್ಲ. ಭಗವಂತನ ಅನುಗ್ರಹವಿಲ್ಲದೆ ನಾವು ನಮ್ಮ ಮನಸ್ಸನ್ನು ಸ್ವತಂತ್ರವಾಗಿ ಎಂದೂ\nನಿಯಂತ್ರಿಸಲು ಸಾಧ್ಯವಿಲ್ಲ. ಹೀಗಿರುವಾಗ ನಾವು ನಮ್ಮ ಮನಸ್ಸನ್ನು ನಿಯಂತ್ರಿಸುವುದು ಹೇಗೆ? ಈ ನಮ್ಮ\nಪ್ರಶ್ನೆಗೆ ಇದೇ ಶ್ಲೋಕದಲ್ಲಿ ಉತ್ತರವಿದೆ.ಆತ್ಮ ಎಂದರೆ ಪರಮಾತ್ಮ ಎನ್ನುವ ಸೂಕ್ಷ್ಮ ಅರ್ಥದಲ್ಲಿ ಈ ಶ್ಲೋಕವನ್ನು\nನೋಡಿದಾಗ ನಮ್ಮ ಪ್ರಶ್ನೆಗೆ oxygen ಸಿಗುತ್ತದೆ. “ಉದ್ಧರೇತ್‌ ಆತ್ಮನಾ ಆತ್ಮಾನಮ್‌” ಅಂದರೆ\n“ಆತ್ಮನಿಂದಲೇ(ಭಗವಂತನಿಂದಲೇ) ಆತ್ಮನನ್ನು(ಜೀವನನ್ನು) ಉದ್ಧರಿಸಬೇಕು. ಸಾಮಾನ್ಯವಾಗಿ ಮನಸ್ಸು\nನಮ್ಮ ಮಾತನ್ನು ಕೇಳುವುದಿಲ್ಲ. “ನನ್ನಿಂದ ಇದು ಸಾಧ್ಯವಿಲ್ಲ” ಎನ್ನುತ್ತದೆ ಮನಸ್ಸು. ಆದರೆ ನಮಗೆ ಭಗವಂತ\nಬುದ್ಧಿ ಕೊಟ್ಟಿದ್ದಾನೆ, ನಾವು ಅದನ್ನು ಉಪಯೋಗಿಸಬೇಕು. ಬುದ್ಧಿಯನ್ನು ಉಪಯೋಗಿಸಿ ಆ ಭಗವಂತನಲ್ಲಿ\n“ನನಗೆ ಒಳ್ಳೆಯ ಮನಸ್ಸನ್ನು ಕೊಡು, ನನ್ನನ್ನು ಉದ್ಧಾರದ ದಾರಿಯಲ್ಲಿ ನಡೆಸು, ಸಾಧನೆ ಮಾಡುವಂತಹ\nಸದ್ದುದ್ಧಿಯನ್ನು ಕೊಡು” ಎಂದು ಆ ಭಗವಂತನಲ್ಲಿ ನಿರಂತರ ಪ್ರಾರ್ಥಿಸು. ಆತ ನಮ್ಮ ಅತ್ಯಂತ ಅತ್ಮೀಯ\nಹಿತಚಿಂತಕ ಬಂಧು. ಅವನೊಬ್ಬನೇ ಯಾವುದೇ ಸ್ವಾರ್ಥವಿಲ್ಲದ, ಶಾಶ್ವತ, ನಿರ್ವ್ಯಾಜ್ಯ, ನಿರಂತರ ಬಂಧು. ಆತ\nಖಂಡಿತ ನಮ್ಮ ಪ್ರಾರ್ಥನೆಯನ್ನು ಮನ್ನಿಸಿ ನಮ್ಮ ಮನಸ್ಸಿನಲ್ಲಿ ಬಂದು ಕೂರುತ್ತಾನೆ.\n\nಭಗವಂತನನ್ನು ನಾವು ಹೇಗೆ ಕಾಣುತ್ತೇವೇ ಅದೇ ಭಾವದಲ್ಲಿ ಆತ ವ್ಯಕ್ತನಾಗುತ್ತಾನೆ. ದೇವತೆಗಳು ಆತನನ್ನು\nಜ್ಞಾನಿಯಾಗಿ ಕಂಡರು- ಆತ ಅವರಿಗೆ ಜ್ಞಾನಿಯಾಗಿ ಕಾಣಿಸಿಕೊಂಡು ಅವರ ಉದ್ಧಾರ ಮಾಡಿದ. ರಾಕ್ಷಸರು ಆತ\nಕೊಲ್ಲುವವ ಮತ್ತು ಶತ್ರು ಎಂದು ತಿಳಿದು ಅವನನ್ನು ದ್ವೇಷಿಸಿದರು- ಆತ ಅವರಿಗೆ ಶತ್ರುವಾಗಿ ಕಾಣಿಸಿದ.\nಅದ್ದರಿಂದ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಆತ್ಮಾ ಏವ ರಿಪುಃ ಆತ್ಮನಃ” ಎಂದು. ಅಂದರೆ ನಾವು ಅಹಂಕಾರದಿಂದ ದಾರಿ\nತಪ್ಪಿದಾಗ ಆತ ನಮಗೆ ನಮ್ಮ ಶತ್ರುವಿನಂತೆ ಭಾಸವಾಗುತ್ತಾನೆ. ಈ ಬಗ್ಗೆ ಮುಂದಿನ ಶ್ಲೋಕ ಇನ್ನೂ ಹೆಚ್ಚಿನ\nಬೆಳಕನ್ನು ಚೆಲ್ಲುತ್ತದೆ.\n\nಬಂಧುರಾತ್ಮಾ$5ತ್ಮನಸ್ತಸ್ಯ ಯೇನಾ*ತ್ಮೈವಾ*ತ್ಮನಾ ಜಿತಃ |\nಅನಾತ್ಮನಸ್ತು ಶತ್ರುತ್ವೇ ವರ್ತೇತಾ*ತ್ಮೈವ ಶತ್ರುವತ್‌         1೬\n\nಬಂಧುಃ ಆತ್ಮಾ ಆತ ಟ್‌ ತಸ್ಯ ಯೇನ ಆತ್ಮಾ ಏವ ಆತ್ಮನಾ ಜಿತಃ ।\n\nಅನಾತ್ಮನಃ ತು ಶತ್ರುತ್ವೇ ವರ್ತೇತ ಆತ್ಮಾ ಏವ ಶತ್ರುವತ್‌--ಯಾವ ಜೀವ ವಿವೇಕದಿಂದ ಬಗೆಯನ್ನು\n[ಭಕ್ತಿಯಿಂದ ಭಗವಂತನನ್ನು]ಗೆದೆಯಬಲ್ಲದೋ [ಯಾವ ಜೀವದಿಂದ ಬಗೆ ಹದಗೊಂಡಿದೆಯೋ], ಅಂತಹ\nಜೀವಕ್ಕೆ ಬಗೆ[ಭಗವಂತ]ಗೆಳೆಯ. ಬಗೆಯನ್ನು[ಭಗವಂತನನ್ನು] ಗೆದೆಯಲಾರದವನಿಗೆ ಬಗೆಯೇ [ಭಗವಂತನೇ\nಹಗೆಯಾಳಿನಂತೆ ಎದುರಾಳಿ.\n\nಯಾರು ಭಗವಂತನನ್ನು ಗೆದ್ದಿದ್ದಾರೋಭಗವಂತನ ಪ್ರೀತಿಗೆ ಪಾತ್ರರಾಗಿದ್ದಾರೋ) ಅವರಿಗೆ ಆತ ಬಂಧು.\nಭಗವಂತನ ಪ್ರೀತಿಗೆ ಪಾತ್ರರಾಗಲು ಆತನ ಅನುಗ್ರಹ ಬೇಕು. ಅವನ ಅನುಗ್ರಹದಿಂದ ಅವನನ್ನು ಒಲಿಸಿ ಅವನ\nಪ್ರೀತಿಗೆ ಪಾತ್ರರಾದವರಿಗೆ ಆತ ಬಂಧು. ಯಾರು ಭಗವಂತನಿಗೆ ಬೆನ್ನು ಹಾಕಿ ಮುಂದೆ ಸಾಗಿದರೋ ಅವರು\nಸದಾ ಭಗವಂತನಿಂದ ದೂರ ಸಾಗುತ್ತಾರೆ. ಆತನಿಗೆ ಬೆನ್ನುಹಾಕಿ ಆತನನ್ನು ದ್ವೇಷಿಸುವವರಿಗೆ ಆತ ಶತ್ರುವಂತೆ\nಕಾಣುತ್ತಾನೆ. ಈ ಕಾರಣದಿಂದ ನಿರಂತರ ಭಗವಂತನನ್ನು ಪ್ರಾರ್ಥಿಸು. “ಬಂಧುವಾಗಿ ನನ್ನೊಳಗೆ ಬಂದು\nನೆಲೆಸು, ನನ್ನನ್ನು ಒಳ್ಳೆಯ ದಾರಿಯಲ್ಲಿ ನಡೆಸು, ನನ್ನನ್ನು ನಿನ್ನತ್ತ ತಿರುಗಿಸಿ ಮುಂದೆ ಕರೆದುಕೊಂಡು ಹೋಗು”\nಎನ್ನುವ ಪ್ರಾರ್ಥನೆ ಹಾಗೂ ಶರಣಾಗತಿ ನಮ್ಮ ಮನಸ್ಸು ಆತನಲ್ಲಿ ನೆಲೆಗೊಳ್ಳುವಂತೆ ಮಾಡುತ್ತದೆ. ಇದು\nಧ್ಯಾನದ ಮೊದಲ ಮೆಟ್ಟಿಲು. ಹೀಗೆ ಮನಸ್ಸನ್ನು ಮಣಿಸಲು ಭಗವಂತನ ಅನುಗ್ರಹಪಡೆಯುವ ಪ್ರಯತ್ನ\nಮಾಡಿದಾಗ ಏನಾಗುತ್ತದೆ ಎನ್ನುವುದನ್ನು ಮುಂದಿನ ಶ್ಲೋಕಗಳಲ್ಲಿ ನೋಡೋಣ.\n\nಜಿತಾತ್ಮನಃ ಪ್ರಶಾಂತಸ್ಯ ಪರಮಾತ್ಮಾ ಸಮಾಹಿತಃ |\nಶೀತೋಷ್ಟಸುಖದುಃಖೇಷು ತಥಾ ಮಾನಾಪಮಾನಯೋಃ",
  "6.6": "ಉದ್ಧರೇತ್‌ ಆತ್ಮನಾ ಆತ್ಮಾನಮ್‌ ನ ಆತ್ಮಾನಮ್‌ ಅವಸಾದಯೇತ್‌ |\n\nಆತ್ಮಾ ಏವಹಿ ಆತ್ಮನಃ ಬಂಧುಃ ಆತ್ಮಾ ಏವ ರಿಪುಃ ಆತ್ಮನಃ -ಬಗೆಯ ಬಲದಿಂದ [ಭಗವಂತನ ಪ್ರಸಾದದಿಂದ]\nಜೀವವನ್ನು ಮೇಲೆತ್ತಬೇಕು; ಜೀವವನ್ನು ಜಂಜಡಗೊಳಿಸಬಾರದು. ಬಗೆಯೇ[ಭಗವಂತನೇ] ಜೀವದ ಗೆಳೆಯ;\nಬಗೆಯೇ[ಭಗವಂತನೇ]ಜೀವದ ಹಗೆಯು.\n\nಈ ಹಿಂದೆ ಹೇಳಿದಂತೆ ಆತ್ಮ ಎನ್ನುವ ಪದಕ್ಕೆ ಅನೇಕ ಅರ್ಥಗಳಿವೆ. ಆತ್ಮ ಎಂದರೆ ಶರೀರ, ಮನಸ್ಸು, ಜೀವ,\nಪರಮಾತ್ಮ. ಹೀಗೆ ಈ ಶ್ಲೋಕದಲ್ಲಿ ಬಂದಿರುವ ಆತ್ಮ ಶಬ್ದಕ್ಕೆ ಈ ಎಲ್ಲಾ ಅರ್ಥವನ್ನೂ ಜೋಡಿಸಿ ನೋಡಿದರೆ\nಅನೇಕ ವಿಚಾರ ಸ್ಪಷ್ಟವಾಗುತ್ತದೆ. “ಉದ್ಧರೇತ್‌ ಆತ್ಮನಾ ಆತ್ಮಾನಮ್‌ ನ ಆತ್ಮಾನಮ್‌ ಅವಸಾದಯೇತ್‌”\nಅಂದರೆ ನಮ್ಮ ಅಧಃಪಾತಕ್ಕೂ ಕಾರಣ ಮನಸ್ಸು. ನಮ್ಮ ಉದ್ಧಾರಕ್ಕೂ ಕಾರಣ ಮನಸ್ಸು. ಆದ್ದರಿಂದ\nಮನಸ್ಸಿನಿಂದ(ಆತ್ಮಾನಾ) ಜೀವದ(ಆತ್ಮಾನಂ) ಉದ್ಧಾರದ ದಾರಿಯನ್ನು ಹುಡುಕು ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಎಂದೂ\nಮನಸ್ಸನ್ನು ಕೆಳಕ್ಕೆ ಕಳುಹಿಸಬೇಡ. ಆತ್ಮದ(ಜೀವದ) ಅವಸಾನಕ್ಕೆ ಕಾರಣವಾಗುವಂತೆ ಮನಸ್ಸನ್ನು\nಸ್ವಚ್ಛಂದವಾಗಿ ಬಿಡಬೇಡ. ಅದನ್ನು ಮೇಲಕ್ಕೆ ಕೊಂಡು ಹೋಗು. ಮನಸ್ಸು ಕೆಳಗೆ ಹೋದರೆ ಅದು ನಮ್ಮನ್ನು\nಪಾತಾಳಕ್ಕೆ ತಳ್ಳಿ ಬಿಡುತ್ತದೆ. \"ಆ ಮನಸ್ಸನ್ನು ಎತ್ತರಕ್ಕೆ ಕಳಿಸು. ಎತ್ತರಕ್ಕೆ ಹೋದ ಮನಸ್ಸು ನಿನ್ನನ್ನು ಎತ್ತರಕ್ಕೆ\nಕೊಂಡೊಯ್ಯುತ್ತದೆ. ಮನಸ್ಸಿನಿಂದ ನಿನ್ನ ಜೀವ ಸ್ವರೂಪವನ್ನು ಉದ್ಧಾರ ಮಾಡಿಕೋ. ಜೀವಕ್ಕೆ ಮನಸ್ಸೇ ಬಂಧು,\nಮನಸ್ಸೇ ಶತ್ರು. ಆದ್ದರಿಂದ ಸಾಧನೆ ಮಾಡಬೇಕಾದರೆ ಮನಸ್ಸನ್ನು ಬಂಧುವಾಗಿ ಪರಿವರ್ತನೆ ಮಾಡಿಕೋ.\nಮನಸ್ಸು ನಿನ್ನ ಶತ್ರುವಾಗಿ ನಿಂತರೆ ನಿನ್ನ ಜೀವಮಾನದಲ್ಲೇ ಉದ್ಧಾರವಿಲ್ಲ. ಅದಕ್ಕಾಗಿ ಮೊದಲು ಬುದ್ಧಿಬಲದಿಂದ\n\nಮನಸ್ಸಿಗೆ ತರಬೇತಿ ಕೊಟ್ಟು ಅದನ್ನು ಗೆಲ್ಲಬೇಕು' ಎನ್ನುವುದು ಕೃಷ್ಣನ ಸಂದೇಶ. ಮನಸ್ಸನ್ನು ಗೆದ್ದರೆ ಎಲ್ಲವೂ\nಪ್ರಶಾಂತ, ಯಾವ ಗೊಂದಲವೂ ಇಲ್ಲ. ಇದು ಧ್ಯಾನಕ್ಕೆ ಬೇಕಾದ ಪೂರ್ವ ಸ್ಥಿತಿ.\n\nಕೃಷ್ಣನ ಈ ಸಂದೇಶ ಕೇಳಿದಾಗ ನಮಗೆ ಒಂದು ಪ್ರಶ್ನೆ ಎದುರಾಗುತ್ತದೆ. ಈ ಹಿಂದೆ ಕೃಷ್ಣನೇ ಹೇಳಿದಂತೆ\nಯಾವುದೂ ನಮ್ಮ ಕೈಯಲ್ಲಿಲ್ಲ. ಭಗವಂತನ ಅನುಗ್ರಹವಿಲ್ಲದೆ ನಾವು ನಮ್ಮ ಮನಸ್ಸನ್ನು ಸ್ವತಂತ್ರವಾಗಿ ಎಂದೂ\nನಿಯಂತ್ರಿಸಲು ಸಾಧ್ಯವಿಲ್ಲ. ಹೀಗಿರುವಾಗ ನಾವು ನಮ್ಮ ಮನಸ್ಸನ್ನು ನಿಯಂತ್ರಿಸುವುದು ಹೇಗೆ? ಈ ನಮ್ಮ\nಪ್ರಶ್ನೆಗೆ ಇದೇ ಶ್ಲೋಕದಲ್ಲಿ ಉತ್ತರವಿದೆ.ಆತ್ಮ ಎಂದರೆ ಪರಮಾತ್ಮ ಎನ್ನುವ ಸೂಕ್ಷ್ಮ ಅರ್ಥದಲ್ಲಿ ಈ ಶ್ಲೋಕವನ್ನು\nನೋಡಿದಾಗ ನಮ್ಮ ಪ್ರಶ್ನೆಗೆ oxygen ಸಿಗುತ್ತದೆ. “ಉದ್ಧರೇತ್‌ ಆತ್ಮನಾ ಆತ್ಮಾನಮ್‌” ಅಂದರೆ\n“ಆತ್ಮನಿಂದಲೇ(ಭಗವಂತನಿಂದಲೇ) ಆತ್ಮನನ್ನು(ಜೀವನನ್ನು) ಉದ್ಧರಿಸಬೇಕು. ಸಾಮಾನ್ಯವಾಗಿ ಮನಸ್ಸು\nನಮ್ಮ ಮಾತನ್ನು ಕೇಳುವುದಿಲ್ಲ. “ನನ್ನಿಂದ ಇದು ಸಾಧ್ಯವಿಲ್ಲ” ಎನ್ನುತ್ತದೆ ಮನಸ್ಸು. ಆದರೆ ನಮಗೆ ಭಗವಂತ\nಬುದ್ಧಿ ಕೊಟ್ಟಿದ್ದಾನೆ, ನಾವು ಅದನ್ನು ಉಪಯೋಗಿಸಬೇಕು. ಬುದ್ಧಿಯನ್ನು ಉಪಯೋಗಿಸಿ ಆ ಭಗವಂತನಲ್ಲಿ\n“ನನಗೆ ಒಳ್ಳೆಯ ಮನಸ್ಸನ್ನು ಕೊಡು, ನನ್ನನ್ನು ಉದ್ಧಾರದ ದಾರಿಯಲ್ಲಿ ನಡೆಸು, ಸಾಧನೆ ಮಾಡುವಂತಹ\nಸದ್ದುದ್ಧಿಯನ್ನು ಕೊಡು” ಎಂದು ಆ ಭಗವಂತನಲ್ಲಿ ನಿರಂತರ ಪ್ರಾರ್ಥಿಸು. ಆತ ನಮ್ಮ ಅತ್ಯಂತ ಅತ್ಮೀಯ\nಹಿತಚಿಂತಕ ಬಂಧು. ಅವನೊಬ್ಬನೇ ಯಾವುದೇ ಸ್ವಾರ್ಥವಿಲ್ಲದ, ಶಾಶ್ವತ, ನಿರ್ವ್ಯಾಜ್ಯ, ನಿರಂತರ ಬಂಧು. ಆತ\nಖಂಡಿತ ನಮ್ಮ ಪ್ರಾರ್ಥನೆಯನ್ನು ಮನ್ನಿಸಿ ನಮ್ಮ ಮನಸ್ಸಿನಲ್ಲಿ ಬಂದು ಕೂರುತ್ತಾನೆ.\n\nಭಗವಂತನನ್ನು ನಾವು ಹೇಗೆ ಕಾಣುತ್ತೇವೇ ಅದೇ ಭಾವದಲ್ಲಿ ಆತ ವ್ಯಕ್ತನಾಗುತ್ತಾನೆ. ದೇವತೆಗಳು ಆತನನ್ನು\nಜ್ಞಾನಿಯಾಗಿ ಕಂಡರು- ಆತ ಅವರಿಗೆ ಜ್ಞಾನಿಯಾಗಿ ಕಾಣಿಸಿಕೊಂಡು ಅವರ ಉದ್ಧಾರ ಮಾಡಿದ. ರಾಕ್ಷಸರು ಆತ\nಕೊಲ್ಲುವವ ಮತ್ತು ಶತ್ರು ಎಂದು ತಿಳಿದು ಅವನನ್ನು ದ್ವೇಷಿಸಿದರು- ಆತ ಅವರಿಗೆ ಶತ್ರುವಾಗಿ ಕಾಣಿಸಿದ.\nಅದ್ದರಿಂದ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಆತ್ಮಾ ಏವ ರಿಪುಃ ಆತ್ಮನಃ” ಎಂದು. ಅಂದರೆ ನಾವು ಅಹಂಕಾರದಿಂದ ದಾರಿ\nತಪ್ಪಿದಾಗ ಆತ ನಮಗೆ ನಮ್ಮ ಶತ್ರುವಿನಂತೆ ಭಾಸವಾಗುತ್ತಾನೆ. ಈ ಬಗ್ಗೆ ಮುಂದಿನ ಶ್ಲೋಕ ಇನ್ನೂ ಹೆಚ್ಚಿನ\nಬೆಳಕನ್ನು ಚೆಲ್ಲುತ್ತದೆ.\n\nಬಂಧುರಾತ್ಮಾತ್ಮನಸ್ತಸ್ಯ ಯೇನಾತ್ಮೈವಾತ್ಮನಾ ಜಿತಃ |\nಅನಾತ್ಮನಸ್ತು ಶತ್ರುತ್ವೇ ವರ್ತೇತಾತ್ಮೈವ ಶತ್ರುವತ್‌ ॥೬॥\n\nಬಂಧುಃ ಆತ್ಮಾ ಆತ ಟ್‌ ತಸ್ಯ ಯೇನ ಆತ್ಮಾ ಏವ ಆತ್ಮನಾ ಜಿತಃ ।\n\nಅನಾತ್ಮನಃ ತು ಶತ್ರುತ್ವೇ ವರ್ತೇತ ಆತ್ಮಾ ಏವ ಶತ್ರುವತ್‌--ಯಾವ ಜೀವ ವಿವೇಕದಿಂದ ಬಗೆಯನ್ನು\n[ಭಕ್ತಿಯಿಂದ ಭಗವಂತನನ್ನು]ಗೆದೆಯಬಲ್ಲದೋ [ಯಾವ ಜೀವದಿಂದ ಬಗೆ ಹದಗೊಂಡಿದೆಯೋ], ಅಂತಹ\nಜೀವಕ್ಕೆ ಬಗೆ[ಭಗವಂತ]ಗೆಳೆಯ. ಬಗೆಯನ್ನು[ಭಗವಂತನನ್ನು] ಗೆದೆಯಲಾರದವನಿಗೆ ಬಗೆಯೇ [ಭಗವಂತನೇ\nಹಗೆಯಾಳಿನಂತೆ ಎದುರಾಳಿ.\n\nಯಾರು ಭಗವಂತನನ್ನು ಗೆದ್ದಿದ್ದಾರೋಭಗವಂತನ ಪ್ರೀತಿಗೆ ಪಾತ್ರರಾಗಿದ್ದಾರೋ) ಅವರಿಗೆ ಆತ ಬಂಧು.\nಭಗವಂತನ ಪ್ರೀತಿಗೆ ಪಾತ್ರರಾಗಲು ಆತನ ಅನುಗ್ರಹ ಬೇಕು. ಅವನ ಅನುಗ್ರಹದಿಂದ ಅವನನ್ನು ಒಲಿಸಿ ಅವನ\nಪ್ರೀತಿಗೆ ಪಾತ್ರರಾದವರಿಗೆ ಆತ ಬಂಧು. ಯಾರು ಭಗವಂತನಿಗೆ ಬೆನ್ನು ಹಾಕಿ ಮುಂದೆ ಸಾಗಿದರೋ ಅವರು\nಸದಾ ಭಗವಂತನಿಂದ ದೂರ ಸಾಗುತ್ತಾರೆ. ಆತನಿಗೆ ಬೆನ್ನುಹಾಕಿ ಆತನನ್ನು ದ್ವೇಷಿಸುವವರಿಗೆ ಆತ ಶತ್ರುವಂತೆ\nಕಾಣುತ್ತಾನೆ. ಈ ಕಾರಣದಿಂದ ನಿರಂತರ ಭಗವಂತನನ್ನು ಪ್ರಾರ್ಥಿಸು. “ಬಂಧುವಾಗಿ ನನ್ನೊಳಗೆ ಬಂದು\nನೆಲೆಸು, ನನ್ನನ್ನು ಒಳ್ಳೆಯ ದಾರಿಯಲ್ಲಿ ನಡೆಸು, ನನ್ನನ್ನು ನಿನ್ನತ್ತ ತಿರುಗಿಸಿ ಮುಂದೆ ಕರೆದುಕೊಂಡು ಹೋಗು”\nಎನ್ನುವ ಪ್ರಾರ್ಥನೆ ಹಾಗೂ ಶರಣಾಗತಿ ನಮ್ಮ ಮನಸ್ಸು ಆತನಲ್ಲಿ ನೆಲೆಗೊಳ್ಳುವಂತೆ ಮಾಡುತ್ತದೆ. ಇದು\nಧ್ಯಾನದ ಮೊದಲ ಮೆಟ್ಟಿಲು. ಹೀಗೆ ಮನಸ್ಸನ್ನು ಮಣಿಸಲು ಭಗವಂತನ ಅನುಗ್ರಹಪಡೆಯುವ ಪ್ರಯತ್ನ\nಮಾಡಿದಾಗ ಏನಾಗುತ್ತದೆ ಎನ್ನುವುದನ್ನು ಮುಂದಿನ ಶ್ಲೋಕಗಳಲ್ಲಿ ನೋಡೋಣ.\n\nಜಿತಾತ್ಮನಃ ಪ್ರಶಾಂತಸ್ಯ ಪರಮಾತ್ಮಾ ಸಮಾಹಿತಃ |\nಶೀತೋಷ್ಟಸುಖದುಃಖೇಷು ತಥಾ ಮಾನಾಪಮಾನಯೋಃ",
  "6.7": "ಜ್ಞಾನವಿಜ್ಞಾನತೃಪ್ತಾತ್ಮಾ ಕೂಟಸ್ಥೋ ವಿಜಿತೇಂದ್ರಿಯಃ |\nಯುಕ್ತ ಇತ್ಯುಚ್ಯತೇ ಯೋಗೀ ಸಮಲೋಷ್ಟಾಶ್ಮಕಾಂಚನಃ",
  "6.8": "ಜಿತ ಆತ್ಮನಃ ಪ್ರಶಾಂತಸ್ಯ ಪರಮ ಆತ್ಮಾ ಸಮಾಹಿತಃ |\n\nಶೀತ ಉಷ್ಣ ಸುಖ ದುಃಖೇಷು ತಥಾ ಮಾನ ಅಪಮಾನಯೋಃ ॥\n\nಜ್ಞಾನ ವಿಜ್ಞಾನ ತೃಪ್ತ ಆತ್ಮಾ ಕೂಟಸ್ಥಃ ವಿಜಿತ ಇಂದ್ರಿಯಃ\n\nಯುಕ್ತಃ ಇತಿ ಉಚ್ಯತೇ ಯೋಗೀ ಸಮಲೋಷ್ಟ ಅಶ್ಮ ಕಾಂಚನಃ -ಬಗೆಯನ್ನು [ಭಕ್ತಿಯಿಂದ ಭಗವಂತನನ್ನು]\nಗೆಲಿದವನ, ವಿಷಯಗಳತ್ತ ಸುಳಿಯದೇ ಭಗವಂತನಲ್ಲೇ ನಲಿದವನ ಬಗೆಯಲ್ಲಿ ಭಗವಂತ ನೆಲೆಗೊಳ್ಳುತ್ತಾನೆ.\nಅಂತವನು ತಂಪು-ಬಿಸಿ, ಸುಖ-ದುಃಖ ಮತ್ತು ಸಮ್ಮಾನ-ತಿರಸ್ಕಾರ ಇಂತಹ ದ್ವಂದ್ವಗಳಲ್ಲಿ ನಿರ್ವಿಕಾರನಾಗಿ\nನಿಲ್ಲಬಲ್ಲವನು; ಭಗವಂತನ ಅರಿವು ಕಾಣ್ಮೆಗಳಿಂದ ಬಗೆದುಂಬಿದವನು; ಇಂದ್ರಿಯಗಳನ್ನು ಹಿಡಿತದಲ್ಲಿಟ್ಟವನು.\nಅವನಿಗೆ ಮಣ್ಣು, ಕಲ್ಲು, ಚಿನ್ನ ಎಲ್ಲಾ ಒಂದೆ. ಇಂತಹ ಯೋಗ ಸಾಧಕನು ಗುರಿ ಸೇರಿದವನು ಎನಿಸುತ್ತಾನೆ.\n\nಭಕ್ತಿಯಿಂದ ಭಗವಂತನ ಅನುಗ್ರಹ ಪಡೆದಾಗ ಮೊದಲು ಮನಸ್ಸು ಆತನಲ್ಲಿ ನೆಲೆ ನಿಲ್ಲುತ್ತದೆ. ಮನಸ್ಸು ಎಂತಹ\nಪ್ರಸಂಗದಲ್ಲೂ ಉದ್ವೇಗಕ್ಕೊಳಗಾಗುವುದಿಲ್ಲ. “ಪರಮಾತ್ಮಾ ಸಮಾಹಿತಃ” -ಭಗವಂತ ಅವನ ಹೃದಯದಲ್ಲಿ\nಬಂದು ನೆಲೆಸಿ ಬಿಡುತ್ತಾನೆ. ನಾವು ಬಯಸಿದಾಗ ಆತನ ಅಂತಃದರ್ಶನ ಸಾಧ್ಯ. ಈ ರೀತಿ ಭಗವಂತನನ್ನು\nಕಾಣುವವರ ಅಪರೋಕ್ಷ ಜ್ಞಾನದ ಪರಿಣಾಮ ಏನು ಎನ್ನುವುದನ್ನು ಇಲ್ಲಿ ಮತ್ತೊಮ್ಮೆ ವಿವರಿಸುತ್ತಾನೆ ಕೃಷ್ಣ.\n\nಮುಖ್ಯವಾಗಿ ಅಪರೋಕ್ಷ ಜ್ಞಾನಿಗಳಿಗೆ ಎಂದೂ ಇಂದ್ರಿಯ ಚಾಪಲ ಕಾಡುವುದಿಲ್ಲ. ಅಪಮಾನಕ್ಕೆ ಆತ ಎಂದೂ\nಕುಸಿಯುವುದಿಲ್ಲ. ಮಾನಾಪಮಾನ ಆತನಿಗೆ ದೊಡ್ಡ ಸಂಗತಿ ಆಗುವುದಿಲ್ಲ. ಈ ಸ್ಥಿತಿ ತಲುಪಿದವ ಸಿದ್ಧ\n\nಎನಿಸುತ್ತಾನೆ. ಆತ ಎಷ್ಟು ನಿರ್ವಿಕಾರ ಎಂದರೆ ಆತ ಎಲ್ಲವನ್ನೂ ಸಮನಾಗಿ ಕಾಣಲಾರಂಭಿಸುತ್ತಾನೆ. ಧನ-ಕನಕ\nಎಲ್ಲವೂ ಬೇಡವೆನಿಸಿ ಅದರಿಂದ ದೂರವಿರುತ್ತಾನೆ. (ರಾಮಕೃಷ್ಣ ಪರಮಹಂಸರ ಆತ್ಮಕಥೆಯನ್ನು ಓದಿದರೆ ಒಬ್ಬ\nಅಪರೋಕ್ಷ ಜ್ಞಾನಿಯ ಮನಃಸ್ಥಿತಿ ನಮಗೆ ಅರ್ಥವಾಗುತ್ತದೆ).\n\nಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ಕೃಷ್ಣ ಧ್ಯಾನಕ್ಕೆ ಪೂರ್ವಭಾವಿಯಾಗಿ ಒಬ್ಬ ಯೋಗಿಯ ಮನಃಸ್ಥಿತಿ ಹೇಗಿರಬೇಕು ಎನ್ನುವ\nಬಹಳ ಮಹತ್ವವಾದ ವಿಚಾರವನ್ನು ವಿವರಿಸುತ್ತಾನೆ.\n",
  "6.9": "ಸುಹೃತ್‌ ಮಿತ್ರ ಅರಿ ಉದಾಸೀನ ಮಧ್ಯಸ್ಥ ದ್ವೇಷ್ಯ ಬಂದುಷು ।\n\nಸಾಧುಷು ಅಪಿ ಚ ಪಾಪೇಷು ಸಮಬುದ್ಧಿಃ ವಿಶಿಷ್ಯತೇ -ಹೆಳೆಯಿಲ್ಲದೇ ಹಚ್ಚಿಕೊಳ್ಳುವವರು, ಕಷ್ಟ ಕಾಲದಲ್ಲಿ\nಎಚ್ಚರಿಸುವವರು, ಕಾಟಕೊಡುವವರು, ಒಳಿತು-ಕೆಡುಕು ಯಾವುದಕ್ಕೂ ಇಲ್ಲದವರು, ಎರಡಕ್ಕೂ ನಿಲ್ಲುವವರು,\nಬೇಡವಾದದ್ದನ್ನು ಬಗೆವವರು, ನೆಂಟರು, ಒಳ್ಳೆಯವರು ಮತ್ತು ಕೆಟ್ಟವರು -ಎಲ್ಲರೂ ಮೂಲತಃ ಜ್ಞಾನ ಸ್ವರೂಪರು\nಎಂದು ಸಮಭಾವದಿಂದ ಕಾಣುವವನು[ಎಲ್ಲರನ್ನೂ ಅವರವರ ಇರವಿಗೆ ತಕ್ಕಂತೆ ಗೌರವಿಸುವವನು]\nಮಿಗಿಲಾದವನು.\n\nಮನಸ್ಸು ಸಮತೋಲನವಾಗದೇ ಧ್ಯಾನ ಮಾಡಲು ಸಾಧ್ಯವಿಲ್ಲ. ಯಾರ್ಯಾರ ಬಗ್ಗೆ ಯಾವುದ್ಯಾವುದೋ\nವಿಚಾರಗಳು ಮನಸ್ಸಿನಲ್ಲಿ ಸುಳಿಯಲಾರಂಭಿಸಿದರೆ ಧ್ಯಾನ ಅಸಾಧ್ಯ. ಪ್ರಪಂಚದಲ್ಲಿ ಅನೇಕ ವಿಧದ\nಜನರಿರುತ್ತಾರೆ. ಉದಾಹರಣೆಗೆ ಸುಹೃತರು-ಅಂದರೆ ಒಳ್ಳೆಯ ಹೃದಯ ಉಳ್ಳವರು. ಯಾವ ಪ್ರತ್ಯುಪಕಾರವನ್ನು\nಬಯಸದೇ ಎಲ್ಲರಿಗೂ ಸಹಾಯ ಮಾಡುವ ಜನರಿವರು. ಇವರ ನಂತರ 'ಮಿತ್ರ'- ತನ್ನ ಆತ್ಮೀಯನಿಗೆ ಸದಾ\nಸಹಾಯ ಮಾಡುವವ, ನಾವು ತಪ್ಪಿದಾಗ ನಮ್ಮನ್ನು ತಿದ್ದುವವನೀತ. ಅರಿಗಳು: ಕೊಲ್ಲುವ ಕೆಟ್ಟ ಶತ್ರುತ್ವ\nಸಾಧಿಸುವ ಇವರಿಗೆ ದ್ವೇಷಿಸಲು ಕಾರಣ ಬೇಡ. ಉದಾಸೀನರು: ಇವರು ಒಳ್ಳೆಯದಕ್ಕೂ ಇಲ್ಲ ಕೆಟ್ಟದ್ದಕ್ಕೂ ಇಲ್ಲ.\nಮಧ್ಯಸ್ಥ: ಒಳ್ಳೆಯದು ಮಾಡಿದಾಗ ಒಳ್ಳೆಯದು, ಕೆಟ್ಟದ್ದು ಮಾಡಿದಾಗ ಕೆಟ್ಟದ್ದು ಮಾಡುವವ. ದ್ವೇಷ್ಯ: ಒಬ್ಬರನ್ನು\nಕಂಡು ಸಹಿಸದವ(hatred). ಕೊನೆಯದಾಗಿ ಬಂಧುಗಳು(Relatives).ಹೀಗೆ ಮಾನವ ಜನಾಂಗದಲ್ಲಿ\nಒಳ್ಳೆಯವರು ಮತ್ತು ಕೆಟ್ಟವರು ತುಂಬಿರುತ್ತಾರೆ.(ದೇವತೆಗಳಲ್ಲಿ- ದಾನವರಲ್ಲಿ ಈ ರೀತಿಯ ಸಮ್ಮಿಶ್ರ ವರ್ಗಗಳಿಲ್ಲ.\nದೇವತೆಗಳು ಕೇವಲ ಸಾಧುಗಳು, ಅಸುರರು ಸದಾ ಪಾಪಿಗಳು, ಆದರೆ ಮಾನವರಲ್ಲಿ ಮಾತ್ರ ಈ ಎರಡು\nಗುಣವಿಶ್ರಿತ ಗುಂಪುಗಳನ್ನು ಕಾಣಬಹುದು). ಧ್ಯಾನದಲ್ಲಿ ನಮಗೆ ಭಗವಂತನ ದರ್ಶನವಾಗಬೇಕಾದರೆ ಮೊದಲು\nನಾವು ನಮ್ಮ ಅಂತರಂಗದಲ್ಲಿ ಈ ಎಲ್ಲಾ ರೀತಿಯ ಜನರ ಬಗ್ಗೆ ಸಮಬುದ್ಧಿಯನ್ನು ಬೆಳೆಸಿಕೊಳ್ಳಬೇಕು. ಒಬ್ಬ\nವ್ಯಕ್ತಿಯ ನಡವಳಿಕೆ ಆತನು ಬೆಳೆದುಬಂದ ವಾತಾವರಣದಿಂದ ಅಥವಾ ತಿಳುವಳಿಕೆ ಇಲ್ಲದೇ ಇದ್ದುದರಿಂದ\nಬಂದದ್ದು ಎಂದು ತಿಳಿದು ಅವನ ಬಗ್ಗೆ ಮನಸ್ಸಿನಲ್ಲಿ ಯಾವ ಕೆಟ್ಟ ಭಾವನೆಯೂ ಇರದಂತೆ ನೋಡಿಕೊಳ್ಳಬೇಕು.\nಒಬ್ಬ ನಮ್ಮ ವೈರಿಯಂತೆ ನಮ್ಮನ್ನು ಕಾಡುತ್ತಿರಬಹುದು. ಇದಕ್ಕೆ ಕಾರಣ ಆತನ ಹಾಗೂ ನಮ್ಮ ಪ್ರಾರಾಬ್ಧ\n\nಕರ್ಮವಿರಬಹುದು. ದೇವರು ಈ ಜನ್ಮದಲ್ಲಿ ಅವನಿಗೆ ಕೊಟ್ಟ ಪಾತ್ರವನ್ನು ಆತ ನಿಭಾಯಿಸುತ್ತಿದ್ದಾನೆ ಎನ್ನುವ\nಭಾವದಲ್ಲಿ ಅವನನ್ನು ನೋಡಿದಾಗ ನಮ್ಮಲ್ಲಿ ದ್ವೇಷ ಹುಟ್ಟು ವುದಿಲ್ಲ. ಇನ್ನೊ ಬ್ಬರು ನಮ್ಮನ್ನು ಬೈದಾಗ ನಾವು\nಉದ್ವೇಗಕ್ಕೊಳಗಾಗುವುದಿಲ್ಲ. \"ಭಗವಂತ ಅವನಿಗೆ ಕೊಟ್ಟ ಪಾತ್ರವನ್ನು ಅದೆಷ್ಟು ಚೆನ್ನಾಗಿ ನಿಭಾಯಿಸುತ್ತಿದ್ದಾನೆ\"\nಎನ್ನುವ ಭಾವ ನಮ್ಮಲ್ಲಿ ಮೂಡಬೇಕು. ಸಂಬಂಧಿಕರಿರಲಿ, ಶತ್ರುಗಳಿರಲಿ, ಯಾರೇ ಇರಲಿ. ಧ್ಯಾನ ಸಮಯದಲ್ಲಿ\nಮನಸ್ಸಿನಲ್ಲಿ ಶುದ್ಧವಾದ ಸಮಭಾವ ನೆಲೆಗೊಂಡಿರಬೇಕು. ಈ ಸ್ಥಿತಿಯಲ್ಲಿ ಧ್ಯಾನಕ್ಕೆ ಕುಳಿತಾಗ ಇವರ್ಯಾರೂ\nಎದುರಿಗೆ ಬರದೆ ಆ ಭಗವಂತನ ದರ್ಶನವಾಗುತ್ತದೆ. ಇಲ್ಲಿ ಒಂದು ಎಚ್ಚರದ ವಿಷಯ ಎಂದರೆ ಅಂತರಂಗದ\nಸಮಭಾವವನ್ನು ವ್ಯವಹಾರಿಕವಾಗಿ ಹೊರ ಪ್ರಪಂಚದಲ್ಲಿ ಅಳವಡಿಸಲು ಬರುವುದಿಲ್ಲ. ವ್ಯವಹಾರಿಕವಾಗಿ ನಾವು\nಹಿಂದೆ ಹೇಳಿದ ಮೈತ್ರಿ, ಕರುಣಾ, ಮುದಿತ ಮತ್ತು ಉಪೇಕ್ಷ ಎನ್ನುವ ನಾಲ್ಕು ಮನೋವೃತ್ತಿಯನ್ನು\nಬೆಳೆಸಿಕೊಳ್ಳಬೇಕು. ಎಲ್ಲರನ್ನೂ ಸಮಾನವಾಗಿ ಕಾಣುವುದು ಅಂದರೆ ಅವರವರನ್ನು ಆಯಾ ಸ್ಥಾನದಲ್ಲಿ\nನೋಡುವುದು ವ್ಯಾವಹಾರಿಕ ಪ್ರಪಂಚದ ಸಮದೃಷ್ಟಿ. ತಂದೆಯನ್ನು ತಂದೆಯಂತೆ, ಮಗನನ್ನು ಮಗನಂತೆ\nಕಂಡು ನಡೆಯುವುದು, ದುಷ್ಟರಿಂದ ದೂರವಿರುವುದು(ಉಪೇಕ್ಷ ವ್ಯಾವಹಾರಿಕ ಪ್ರಪಂಚ... ಅಂತರಂಗ\nಪ್ರಪಂಚದಲ್ಲಿ ನಾವು ಎಲ್ಲರಲ್ಲೂ ಆತನ ಒಳಗಿರುವ ಭಗವಂತನನ್ನು ಮಾತ್ರ ಕಾಣಬೇಕು. ಇದು ಧ್ಯಾನಕ್ಕೆ\nಬೇಕಾದ ಪೂರ್ವಭಾವಿ ಮನಃಸ್ಥಿತಿ. ಮಾನಸಿಕವಾಗಿ ಎಲ್ಲಾ ಸಂಬಂಧದ ನಂಟನ್ನು ಕಳಚಿ ಧ್ಯಾನಕ್ಕೆ\nಕುಳಿತುಕೊಳ್ಳಬೇಕು. ಧ್ಯಾನದಲ್ಲಿ ತಂದೆ, ತಾಯಿ, ಗುರು, ಶಿಷ್ಯ, ವೈರಿ, ಮಿತ್ರ ಇತ್ಯಾದಿ ವರ್ಗಗಳಿಲ್ಲ. ಎಲ್ಲವೂ\nಒಂದೇ, ಅದು ಕೇವಲ ಜ್ಞಾನಸ್ವರೂಪವಾದ ಜೀವ- ಅದರೊಳಗೆ ಬಿಂಬ ರೂಪಿ ಭಗವಂತ. ಇದು ಧ್ಯಾನಕ್ಕೆ\nಬೇಕಾದ ಮಾನಸಿಕ ಸ್ಥಿತಿ.\n\nಹೀಗೆ ಧ್ಯಾನಕ್ಕೆ ಬೇಕಾದ ಪೂರ್ವ ಸಿದ್ಧತೆಯನ್ನು ವಿವರಿಸಿದ ಕೃಷ್ಣ ಮುಂದೆ ನೇರವಾಗಿ ಧ್ಯಾನಕ್ಕೆ ಕೂರುವ\nವಿಧಾನವನ್ನು ವಿವರಿಸುತ್ತಾನೆ.\n",
  "6.10": "ಯೋಗೀ ಯುಂಜೀತ ಸತತಮ್‌ ಆತ್ಮಾನಮ್‌ ರಹಸಿ ಸ್ಥಿತಃ |\n\nಏಕಾಕೀ ಯತ ಚಿತ್ತ ಆತ್ಮಾ ನಿರಾಶೀಃ ಅಪರಿಗ್ರಹಃ -ಯೋಗ ಸಾಧಕನು ಒಬ್ಬನೇ ಏಕಾಂತದಲ್ಲಿ ಕುಳಿತು,\nಮೈಮನಗಳನ್ನು ಹದಗೊಳಿಸಿ, ಆಸೆಪಡದೆ, ಏತಕ್ಕೂ ಕೈಯೊಡ್ಡದೆ, ಬಗೆಯನ್ನು ಸದಾ ಸಮಾಧಿಗೆ\nಅಣಿಗೊಳಿಸಬೇಕು.\n\nಧ್ಯಾನ ಮಾರ್ಗದಲ್ಲಿ ಸಾಧನೆ ಮಾಡತಕ್ಕಂತಹ ವ್ಯಕ್ತಿ ಮನಸ್ಸನ್ನು ನಿರಂತರ ಧ್ಯಾನ ಯೋಗದಲ್ಲಿ ತೊಡಗಿಸಲು\nಹಾಗೂ ಏಕಾಗ್ರಗೊಳಿಸಲು ಪ್ರಯತ್ನ ಪಡಬೇಕು. ಜನಜಂಗುಳಿ ಇದ್ದಲ್ಲಿ ಧ್ಯಾನ ಅಭ್ಯಾಸ ಮಾಡಲು ಅಸಾಧ್ಯ. ಈ\nಕಾರಣಕ್ಕಾಗಿ ಹಿಂದಿನವರು ಧ್ಯಾನಕ್ಕಾಗಿ ಬೆಳಗಿನ ಜಾವದ ಅರುಣೋದಯ ಕಾಲವನ್ನು ಮೀಸಲಿಡುತ್ತಿದ್ದರು.\n\nಬೆಳಗಿನಜಾವ ಸೂರ್ಯೋದಯಕ್ಕಿಂತ ತೊಂಬತ್ತಾರು ನಿಮಿಷ ಮೊದಲು ಧ್ಯಾನಕ್ಕೆ ಕುಳಿತರೆ ಆಗ ಇಡೀ ಪ್ರಕೃತಿ\nಪ್ರಶಾಂತವಾಗಿರುತ್ತದೆ. ಈ ಕಾಲ ಮನಸ್ಸನ್ನು ಏಕಾಗ್ರತೆಗೆ ಕೊಂಡೊಯ್ಯಲು ಅತ್ಯಂತ ಪೂರಕ ಕಾಲ. ಇದನ್ನು\n'\"ಬ್ರಹ್ಮಮುಹೂರ್ತ' ಎನ್ನುತ್ತಾರೆ [ಸೂರ್ಯೋದಯಕ್ಕಿಂತ ತೊಬತ್ತಾರು ನಿಮಿಷ(ನಾಲ್ಕು ಘಳಿಗೆ) ಮೊದಲು\nಪ್ರಾರಂಭವಾಗಿ ನಲವತ್ತೆಂಟು ನಿಮಿಷಗಳ ಕಾಲ(ಎರಡು ಘಳಿಗೆ? ಬ್ರಹ್ಮಮುಹೂರ್ತ. ಉದಾಹರಣೆಗೆ\nಸೂರ್ಯೋದಯ 5:44ಕ್ಕೆ ಆದರೆ 4:08 ರಿಂದ 4:56 ರ ತನಕ ಬ್ರಹ್ಮಮುಹೂರ್ತ]. ಈ ಮುಹೂರ್ತದ ದೇವತೆ\nಚತುರ್ಮುಖ ಬ್ರಹ್ಮ. ಈತನೇ ನಮ್ಮ ಚಿತ್ತದ ದೇವತೆ. ಆದ್ದರಿಂದ ಈ ಕಾಲ ಜಪ ಸ್ಮರಣೆ ಮತ್ತು ಧ್ಯಾನಕ್ಕೆ\nಅತ್ಯಂತ ಶ್ರೇಷ್ಠವಾದ ಸಮಯ. ಧ್ಯಾನ ಎನ್ನುವುದು ಅತ್ಯಂತ ಅಂತರಂಗದ ಕ್ರಿಯೆ. ಇಲ್ಲಿ ಕೇವಲ ಭಗವಂತ\nಮತ್ತು ಸಾಧಕ ಜೀವ ಮಾತ್ರ ಇರಬೇಕು. ಮೂರನೇ ಸಂಗಾತಿ ಬಂದರೆ ತೊಂದರೆಯಾಗುತ್ತದೆ. ಒಬ್ಬ ಕಲುಷಿತ\nಮನಸ್ಸಿ ನ(polluted mind) ವ್ಯಕ್ತಿಯಿಂದ ಆತನ ಸುತ್ತಲಿನ ವಾತಾವರಣ ಕೆಡುತ್ತದೆ. ಅದಕ್ಕಾಗಿ ಧ್ಯಾನ ಅಭ್ಯಾಸ\nಮಾಡುವಾಗ ಯಾವಾಗಲೂ ಏಕಾಂತವಾಗಿ ಅಭ್ಯಾಸ ಮಾಡಬೇಕು. ನಮ್ಮ ಚಿತ್ತ ಮತ್ತು ಮನಸ್ಸನ್ನು\nನಿಯಂತ್ರಣದಲ್ಲಿಟ್ಟು, ಯಾವುದೇ ಆಸೆ ಆಕಾಂಕ್ಷೆ ಮನಸ್ಸಿಗೆ ಸುಳಿಯದಂತೆ, ತೃಪ್ತ ಮನಸ್ಸಿನಿಂದ ಧ್ಯಾನಕ್ಕೆ\nಅಣಿಯಾಗಬೇಕು.\n\nಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ಧ್ಯಾನಕ್ಕೆ ಕೂರುವ ಸ್ಥಳ ಹೇಗಿರಬೇಕು ಮತ್ತು ಹೇಗೆ ಕುಳಿತುಕೊಳ್ಳಬೇಕು ಎನ್ನುವುದನ್ನು\nಕೃಷ್ಣ ವಿವರಿಸುತ್ತಾನೆ.",
  "6.11": "ತತ್ರೈಕಾಗ್ರಂ ಮನಃ ಕೃತ್ವಾ ಯಶಚಿತ್ತೇಂದ್ರಿಯಕ್ರಿಯಃ |\nಉಪವಿಶ್ಯಾ$ಸನೇ ಯುಂಜ್ಯಾದ್‌ ಯೋಗ ಮಾತ್ಮವಿಶುದ್ಧಯೇ",
  "6.12": "ಶುಚೌ ದೇಶೇ ಪ್ರತಿಷ್ಠಾಪ್ಯ ಸ್ಥಿರಮ್‌ ಆಸನಮ್‌ ಆತ್ಮನಃ |\n\nನ ಅತಿ ಉಚ್ಛಿ ತಮ್‌ ನ ಅತಿ ನೀಚಮ್‌ ಚೇಲ ಅಜಿನ ಕುಶ ಉತ್ತರಮ್‌\n\nತತ್ರ ಏಕ ಅಗ್ರಮ್‌ ಮನಃ ಕೃತ್ವಾ ಯಶಚಿತ್ತ ಇಂದ್ರಿಯ ಕ್ರಿಯ; ।\n\nಉಪವಿಶ್ಯ ಆಸನೇ ಯುಂಜ್ಯಾತ್‌ ಯೋಗಮ್‌ ಆತ್ಮ ವಿಶುದ್ಧಯೇ -ನಿರ್ಮಲವಾದ ತಾಣದಲ್ಲಿ, ಹುಲ್ಲ(ದರ್ಬೆ)\nಚಾಪೆ-ಜಿಂಕೆಯ ತೊಗಲ ಮೇಲೆ ಬಟ್ಟೆ ಹಾಸಿ, ತುಂಬಾ ಎತ್ತರವೂ ಅಲ್ಲದ, ತೀರಾ ತಗ್ಗೂ ಅಲ್ಲದ, ನಲುಗದ\nಆಸನವನ್ನು ತನಗಾಗಿ ಅಣಿಗೊಳಿಸಬೇಕು. ಅದರಲ್ಲಿ ಕುಳಿತು, ಬಗೆಯನ್ನು ನೆಟ್ಟ ಗುರಿಯಲ್ಲಿರಿಸಿ, ಇಂದ್ರಿಯಗಳ\nಮತ್ತು ಒಳಬಗೆಯ ಚೆಲ್ಲಾಟವನ್ನು ನಿಲ್ಲಿಸಿ, ಆತ್ಮ ಶುದ್ಧಿಗಾಗಿ ಸಮಾಧಿಯನ್ನು ಸಾಧಿಸಬೇಕು.\n\nಧ್ಯಾನಕ್ಕೆ ಕೂರುವ ಪ್ರದೇಶ ಸ್ವಚ್ಛವಾಗಿರಬೇಕು. ಮನೆಯಲ್ಲಿ ಸಾತ್ವಿಕ ಕಂಪನ(Vibration)ವಿರುವ ಸ್ಥಳವನ್ನು\nಧ್ಯಾನಕ್ಕೆ ಆರಿಸಿಕೊಳ್ಳಬೇಕು. ಹಿಂದೆ ಮನೆಯಲ್ಲಿ ಹೆಚ್ಚು ಸಾತ್ವಿಕ ಕಂಪನವಿರುವ ಸ್ಥಳವನ್ನು ಗುರುತಿಸಿ ಅಲ್ಲಿ\nದೇವರಮನೆಯನ್ನು ನಿರ್ಮಿಸುತ್ತಿದ್ದರು. ದುರಾದೃಷ್ಟಾವಶಾತ್‌ ಇಂದು ಮನೆ ಕಟ್ಟುವಾಗ ಎಲ್ಲಿ ಜಾಗ\nಉಳಿದಿರುತ್ತದೋ ಅದನ್ನು ದೇವರಮನೆಯಾಗಿ ಪರಿವರ್ತಿಸುತ್ತಿದ್ದೇವೆ. ನಾವು. ಮನೆಯಲ್ಲಿ ಯಾವ ಭಾಗದಲ್ಲಿ\nಕುಳಿತಾಗ ನಮಗೆ ಮನಸ್ಸು ಪ್ರಸನ್ನವಾಗಿ ದೇವರ ಧ್ಯಾನಕ್ಕೆ ಪೂರಕವಾಗಿರುತ್ತದೋ ಅಲ್ಲಿ ಸಾತ್ವಿಕ ಕಂಪನ\nಹೆಚ್ಚಾಗಿದೆ ಎಂದು ನಾವು ಸುಲಭವಾಗಿ ಕಂಡು ಹಿಡಿಯಬಹುದು. ಇದನ್ನೇ ಇಲ್ಲಿ “ಶುಚಿ ದೇಶ” ಎಂದಿದ್ದಾರೆ.\n\nನಾವು ಸಾತ್ವಿಕ ಕಂಪನವಿರುವ ಸ್ಥಳವನ್ನು ಗುರುತಿಸಿದರೆ ಸಾಲದು; ಅಲ್ಲಿ ಎಷ್ಟು ಒಳ್ಳೆಯ ಸಾತ್ವಿಕ\nಕಂಪನವಿದ್ದರೂ ನಾವು ನೆಲದಲ್ಲಿ ಕುಳಿತರೆ ನೆಲದಲ್ಲಿರುವ ಕೆಟ್ಟ ಕಂಪನ ನಮ್ಮ ದೇಹವನ್ನು ಪ್ರವೇಶಿಸಬಹುದು.\nಅದಕ್ಕಾಗಿ ನಾವು ಕುಳಿತುಕೊಳ್ಳುವ ಆಸನ ವ್ಯವಸ್ಥೆ ಸರಿಯಾಗಿರಬೇಕು. ಸ್ಥಿರವಾದ ಆಸನ ಅತೀ ಮುಖ್ಯ.\nಇದಕ್ಕಾಗಿ ಸೋಫಾದಂತಹ ಕುಶನ್‌ ಇರುವ ಆಸನವನ್ನು ಉಪಯೋಗಿಸಬಾರದು. ಇಲ್ಲಿ ಕೃಷ್ಣ ಯಾವ ರೀತಿಯ\nಆಸನ ಯೋಗ್ಯ ಎನ್ನುವುದನ್ನು ವಿವರಿಸಿದ್ದಾನೆ. ನಾವು ಕುಳಿತುಕೊಳ್ಳುವ ಆಸನ ಬಹಳ ತಗ್ಗಾಗಿ ಇರಬಾರದು,\nಬಹಳ ಎತ್ತರದಲ್ಲಿಯೂ ಇರಬಾರದು. ಕುಳಿತುಕೊಳ್ಳುವ ಸ್ಥಳದಲ್ಲಿ ಮೊದಲು ದರ್ಬೆಯ ಚಾಪೆಯನ್ನು ಹಾಸಬೇಕು.\nಅದರ ಮೇಲೆ ಕೃಷ್ಣಾಜಿನವನ್ನು(ಸಂಸಾರಿಗಳು) ಅಥವಾ ವ್ಯಾಘ್ರಾಜಿನ(ಸಂಸಾರವನ್ನು ತ್ಯಜಿಸಿದ-ನೈಷ್ಠಿಕ\nಬ್ರಹ್ಮಚಾರಿಗಳು)ವನ್ನು ಹಾಸಬೇಕು. ಅದರ ಮೇಲೆ ಬಟ್ಟೆ (ರೇಷ್ಮೆಯ ಪಟ್ಟೆ ಅಥವಾ ದಾವಳಿ). ಇದು ಧ್ಯಾನಕ್ಕೆ\nಅತ್ಯಂತ ಶ್ರೇಷ್ಠ ಆಸನ.\n\nಇಲ್ಲಿ ದರ್ಬೆಯ ಚಾಪೆಯನ್ನು ಉಪಯೋಗಿಸಲು ಹೇಳಿದ್ದಾರೆ. ಮೇಲ್ನೊ ಟಕ್ಕೆ ದರ್ಬೆ ವ್ಯರ್ಥವಾಗಿ ಬೆಳೆಯುವ\nಹುಲ್ಲು; ಆದರೆ ವಾತಾವರಣದಲ್ಲಿರುವ ದುಷ್ಟಶಕ್ತಿಯನ್ನು ನಿಯಂತ್ರಿಸುವ ಅಮೋಘ ಶಕ್ತಿ ದರ್ಬೆಗಿದೆ. ಅದಕ್ಕಾಗಿ\nಯಜ್ಞ-ಯಾಗದಿಗಳಲ್ಲಿ ದರ್ಬೆಯನ್ನು ಉಂಗುರವಾಗಿ ಧರಿಸುತ್ತಾರೆ ಹಾಗೂ ದುಷ್ಟ ಶಕ್ತಿ ನಿಯಂತ್ರಕವಾಗಿ\nಯಜ್ಞಕುಂಡದ ಸುತ್ತಲೂ ದರ್ಬೆಯನ್ನು ಇಡುತ್ತಾರೆ. ಧ್ಯಾನ ಕಾಲದಲ್ಲಿ ಯಾವುದೇ ದುಷ್ಟಶಕ್ತಿಗಳು ನಮಗೆ\nತೊಂದರೆ ಕೊಡದಂತೆ ಇಲ್ಲಿ ದರ್ಬೆಯ ಚಾಪೆ ನಮಗೆ ಸಹಾಯ ಮಾಡುತ್ತದೆ. ಕೃಷ್ಣಾಜಿನ ಹಾಗೂ ಪಟ್ಟೆ\nಮಹತ್ತಾದ ಸಾತ್ವಿಕ ಕಂಪನವನ್ನು ನಮಗೊದಗಿಸುತ್ತದೆ. ಇದು ನೆಲದಿಂದ ನಮ್ಮ ದೇಹಕ್ಕೆ ಕೆಟ್ಟ ಕಂಪನ\nಪ್ರವೇಶಿಸದಂತೆ ತಡೆಯುತ್ತದೆ. ನಮ್ಮಲ್ಲಿ ಕೆಲವರು ಮರದ ಮಣೆಯನ್ನು ಉಪಯೋಗಿಸುತ್ತಾರೆ. ಆದರೆ\nಮಣೆಯಲ್ಲಿ ಕುಳಿತಾಗ ನಮ್ಮ ದೇಹದ ಕೆಲವು ಭಾಗ ನೆಲವನ್ನು ಸ್ಪರ್ಶಿಸುವ ಸಾಧ್ಯತೆ ಇದೆ. ಅದಕ್ಕಾಗಿ ಕೃಷ್ಣ\nಹೇಳಿದ ಈ ಮೇಲಿನ ಆಸನ ಬಹಳ ಸೂಕ್ತ. ಈ ರೀತಿಯ ಆಸನವನ್ನು ತಯಾರಿಸಿಕೊಂಡು ನಮಗೆ ಸಾಧ್ಯವಾದ\nಭಂಗಿ(Posture)ಯಲ್ಲಿ ನೆಟ್ಟಗೆ ಕುಳಿತುಕೊಳ್ಳಬೇಕು. ನಮಗೆ ಸಾಧ್ಯವಾಗದ ಆಸನದಲ್ಲಿ ಬಲವಂತವಾಗಿ\nಕೂರುವುದು ಧ್ಯಾನಕ್ಕೆ ಪೂರಕವಲ್ಲ. ಸಾಮಾನ್ಯವಾಗಿ ವಜ್ರಾಸನ ಬಹಳ ಪ್ರಸಿದ್ಧ. ಈ ಆಸನದಲ್ಲಿ ನಮ್ಮ ದೇಹ\nನೆಟ್ಟಗಿರುತ್ತದೆ ಹಾಗೂ ಇದು ಧ್ಯಾನಕ್ಕೆ ಪೂರಕ. ಈ ಬಗ್ಗೆ ಮುಂದೆ ವಿವರವಾಗಿ ಕೃಷ್ಣ ವಿವರಿಸುತ್ತಾನೆ.\n\nಮೇಲೆ ಹೇಳಿದ ರೀತಿ ಆಸನವನ್ನು ಸಿದ್ಧ ಪಡಿಸಿಕೊಂಡು ಕುಳಿತ ತಕ್ಷಣ ಧ್ಯಾನ ಸಾಧ್ಯವಾಗುವುದಿಲ್ಲ. ಆಸನದ\nಮೇಲೆ ಸೂಕ್ತ ಭಂಗಿಯಲ್ಲಿ ಕೂತು ಮನಸ್ಸನ್ನು ಭಗವಂತನ ಕಡೆಗೆ ಏಕಾಗ್ರ ಮಾಡಬೇಕು. “ಏಕಾಗ್ರ' ಎನ್ನುವ\nಪದಕ್ಕೆ ಎರಡು ಅರ್ಥವಿದೆ. ಏಕ-ಅಗ್ರ-ಬಾಣದಂತೆ ಒಂದೇ ಗುರಿ. ಯಾವುದಕ್ಕೆ ಗುರಿ ಇಡುವುದು ಎಂದರೆ ಅದಕ್ಕೆ\n\nಇದೇ ಪದದಲ್ಲಿ ಉತ್ತರವಿದೆ. \"ಏಷ ಏವ ಕರೋತೀತಿ ಏಕಾಗ್ರಹಃ-ಯಾರೊಬ್ಬನು ಈ ಜಗತ್ತಿನ ಸೃಷ್ಠಿ-ಸ್ಥಿತಿ-\nಸಂಹಾರ-ನಿಯಮನ-ಜ್ಞಾನಾಜ್ಞಾನ-ಬಂಧ-ಮೋಕ್ಷಗಳಿಗೆ ಕಾರಣನೋ ಅವನಲ್ಲಿ ಮನಸ್ಸನ್ನು ನೆಲೆಗೊಳಿಸುವುದು\nಏಕಾಗ್ರ. ಬಾಲ್ಯದಿಂದ ಬೆಳೆಸಿಕೊಂಡು ಬಂದ ಅಭ್ಯಾಸವನ್ನು ಬಿಟ್ಟು ಹೊಸ ಅಭ್ಯಾಸಕ್ಕೆ ತನ್ನನ್ನು ತಾನು\nಅಣಿಗೊಳಿಸಬೇಕಾದರೆ ಮನಸ್ಸಿಗೆ ಬಹಳ ಸಮಯ ಬೇಕಾಗುತ್ತದೆ. ಹೀಗಾಗಿ ಧ್ಯಾನಕ್ಕೆ ಕೂತ ತಕ್ಷಣ ಮನಸ್ಸು\nಏಕಾಗ್ರವಾಗಲಿಲ್ಲ ಎಂದು ಯಾರೂ ಗಾಬರಿಯಾಗುವುದು ಬೇಡ. ನಿರಂತರ ಪ್ರಯತ್ನವನ್ನು ಎಂದೂ ಕೈಬಿಡದೆ\nಛಲದಿಂದ ಸಾಧನೆ ಮಾಡಿದಾಗ ಏಕಾಗ್ರತೆ ಸಾಧ್ಯ.\n\nಮನಸ್ಸು ಏಕಾಗ್ರವಾದ ನಂತರ 'ಯಶಚಿತ್ತ ಇಂದ್ರಿಯ ಕ್ರಿಯಃ' - ಎಲ್ಲಾ ಬಾಹ್ಯಇಂದ್ರಿಯ ಕ್ರಿಯೆಯನ್ನು\nಸಂಪೂರ್ಣ ಸ್ಥಬ್ಧಗೊಳಿಸಬೇಕು. ಅಂದರೆ ಈ ಸ್ಥಿತಿಯಲ್ಲಿ ಹೊರಗಿನ ಶಬ್ದ ನಮಗೆ ಕೇಳಿಸದು, ಬಾಹ್ಯ ಕಂಪು\nಮೂಗಿಗೆ ಬಡಿಯದು. ಒಂದು ವೇಳೆ ಒಂದು ಸೊಳ್ಳೆ ಕಚ್ಚಿದರೂ ಆ ನೋವಿನ ಅರಿವು ನಮಗಾಗುವುದಿಲ್ಲ. ಇದು\nನಿದ್ದೆಯಂತೆ; ನಿದ್ದೆಯಲ್ಲಿ ನಮಗೆ ಅಂತರಂಗ ಪ್ರಪಂಚ ಎಚ್ಚರವಿರುವುದಿಲ್ಲ, ಆದರೆ ಧ್ಯಾನದಲ್ಲಿ ಅಂತರಂಗ\nಪ್ರಪಂಚ ಎಚ್ಚರವಿರುತ್ತದೆ. ಹೀಗೆ ಬಾಹ್ಯೇಂದ್ರಿಯ ಕ್ರಿಯೆಯನ್ನು ಸ್ಥಬ್ಧಗೊಳಿಸಿ ನಂತರ ಚಿತ್ತವನ್ನು\nನಿಯಂತ್ರಿಸಬೇಕು. ನಮ್ಮ ಚಿತ್ತದಲ್ಲಿ ಅದೆಷ್ಟು ವಿಚಾರ ಸಂಗ್ರಹವಾಗಿರುತ್ತದೆ. ಆದರೆ ಹಿಂದೆ ದಾಖಲಿಸಿರುವ ಎಲ್ಲಾ\nವಿಷಯಗಳನ್ನು ಬಿಟ್ಟು ಕೇವಲ ಭಗವಂತನ ಗುಣದ ಅಂಶವನ್ನು ಮಾತ್ರ ಧ್ಯಾನ ಮಾಡಬೇಕು.\n\nಹೀಗೆ ನಮ್ಮ ಮನಸ್ಸು ಚಿತ್ತವನ್ನು ನಿಯಂತ್ರಿಸಲು ಜನ್ಮ ಜನ್ಮಾಂತರದ ಸಾಧನೆ ಬೇಕು. ಕೆಲವರು ಈ\nಸಾಧನೆಯಲ್ಲಿ ನಿರಂತರ ಪ್ರಯತ್ನ ಮಾಡಿ ಯಾವುದೇ ಸಿದ್ಧಿಫಲಿಸದೇ ನಿರಾಶರಾಗುವುದಿದೆ. ಆದರೆ ಹಿಂದೆ\nಹೇಳಿದಂತೆ ನಾವು ಅಧ್ಯಾತ್ಮದಲ್ಲಿ ಇಡುವ ಒಂದು ತೊದಲು ಹೆಜ್ಜೆ ಕೂಡಾ ವ್ಯರ್ಥವಲ್ಲ. ಈ ಜನ್ಮದಲ್ಲಿ ಸಿದ್ಧಿ\nಸಾಧ್ಯವಾಗದೇ ಇದ್ದರೆ, ಖಂಡಿತ ಮುಂದಿನ ಜನ್ಮದಲ್ಲಿ ನಮ್ಮ ಸಾಧನೆ ಈ ಜನ್ಮದಲ್ಲಿ ಎಲ್ಲಿ ನಿಂತಿತ್ತೋ\nಅಲ್ಲಿಂದಲೇ ಆರಂಭವಾಗುತ್ತದೆ(ಈ ಬಗ್ಗೆ ವಿವರವಾಗಿ ಮುಂದೆ ಕೃಷ್ಣ ವಿವರಿಸುತ್ತಾನೆ). ಆದ್ದರಿಂದ ಎಂದೂ\nನಿರಾಶೆ ಬೇಡ, ಪ್ರಯತ್ನ ಮಾತ್ರ ನಿರಂತರವಾಗಿರಲಿ.\n\nಹೀಗೆ ನಮ್ಮ ಮನಸ್ಸು ಮತ್ತು ಚಿತ್ತ ನಿಯಂತ್ರಣಕ್ಕೆ ಬಂದ ಮೇಲೆ ನಾವು ಅದನ್ನು ಅದೇ ಸ್ಥಿತಿಯಲ್ಲಿ\nಹಿಡಿದಿಟ್ಟುಕೊಳ್ಳಬೇಕು(ಯುಂಜ್ಯಾದ್‌ ಯೋಗಮ್‌). ಈ ಸ್ಥಿತಿಯಲ್ಲಿ ನಮ್ಮ ಜ್ಞಾನಾನಂದಮಯವಾದ ಅತ್ಮಕ್ಕೆ\nಹಿಡಿದ ಕೊಳೆ ತೊಳೆದುಹೋಗಿ ಆತ್ಮಶುದ್ಧಿಯಾಗುತ್ತದೆ. ಇಂತಹ ಶುದ್ಧವಾದ ಆತ್ಮದಿಂದ ಪವಿತ್ರನಾದ\nಭಗವಂತನನ್ನು ಕಾಣಲು ಸಾಧ್ಯ.\n\nಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ಕೃಷ್ಣ ಧ್ಯಾನ ಭಂಗಿ(ಕುಳಿತುಕೊಳ್ಳುವ ರೀತಿ)ಯ ಬಗ್ಗೆ ಇನ್ನೂ ಸ್ಪಷ್ಟವಾದ ಚಿತ್ರಣವನ್ನು\nಕೊಡುತ್ತಾನೆ.\n\nಮಂ ಕಾಯಶಿರೋಗ್ರೀವಂ ಧಾರಯನ್ನಚಲಂ ಸ್ಥಿರಃ |\n೦ಪ್ರೇಕ್ಷ್ಯ ನಾಸಿಕಾಗ್ರಂ ಸ್ವಂ ದಿಶಶ್ವಾನವಲೋಕಯನ್‌",
  "6.13": "ಹ\nು\nಹ\nು\n\nಪ್ರಶಾಂತಾತ್ಮಾ ವಿಗತಭೀರ್ಬ್ರ",
  "6.14": "ಸಮಮ್‌ ಕಾಯ ಶಿರಃ ಗ್ರೀವಮ್‌ ಧಾರಯನ್‌ ಅಚಲಮ್‌ ಸ್ಥಿರಃ ।\n\nಸಂಪ್ರೇಕ್ಷ್ಯ ನಾಸಿಕಾ ಅಗ್ರಮ್‌ ಸ್ವಮ್‌ ದಿಶಃ ಚ ಅನವಲೋಕಯನ್‌ |\n\nಪ್ರಶಾಂತ ಆತ್ಮಾ ವಿಗತ ಭೀಃ ಬ್ರಹ್ಮಚಾರಿವ್ರತೇ ಸ್ಥಿತಃ |\n\nಮನಃ ಸಂಯಮ್ಯ ಮತ್‌ ಚಿತ್ತಃ ಯುಕ್ತಃ ಆಸೀತ ಮತ್‌ ಪರಃ - ಬೆನ್ನು-ತಲೆ-ಕತ್ತನ್ನು ನೆಟ್ಟಗೆ ನಿಲ್ಲಿಸಿ, ನಲುಗದೇ\nಗಟ್ಟಿಯಾಗಿ ಕುಳಿತು, ಅತ್ತಿತ್ತ ನೋಡದೇ ತನ್ನ ಮೂಗಿನ ತುದಿಯಲ್ಲೇ ನೋಟವಿಟ್ಟು, ಬಗೆಯನ್ನು ವಿಷಯಗಳತ್ತ\nಹರಿಯಗೊಡದೆ ಹದಗೊಳಿಸಿ, ಅಂಜದೆ, ಬ್ರಹ್ಮಚರ್ಯದಲ್ಲಿದ್ದು, ನನ್ನನ್ನೇ ಪರದೈವವೆಂದು ನಂಬಿ, ನನ್ನನ್ನೇ\nನೆನೆಯುತ್ತಾ ಸಮಾಧಿಯನ್ನು ಸಾಧಿಸಬೇಕು.\n\nಧ್ಯಾನಕ್ಕೆ ಕುಳಿತಾಗ ಸೊಂಟದಿಂದ ಮೇಲಿನ ನಮ್ಮ ಶರೀರ ನೆಟ್ಟಗೆ ಸರಳರೇಖೆಯಲ್ಲಿರಬೇಕು. ಬೆನ್ನು\nಬಗ್ಗಿರಕೂಡಾದು, ಕುತ್ತಿಗೆ, ತಲೆ. ವಾಲಿರಬಾರದು. ದೇಹವನ್ನು ನಿಶ್ಚಲಗೊಳಿಸಬೇಕು. ಸ್ವಲ್ಪವೂ\nಅಲ್ಲಡಿಸಬಾರದು. ಈ ರೀತಿ ಕುಳಿತುಕೊಳ್ಳದೇ ಮನಸ್ಸಿನ ಸ್ಥಿರತೆ ಅಸಾಧ್ಯ. ಮನಸ್ಸು ಈ ದೇಹವೆಂಬ\nಪಾತ್ರೆಯೊಳಗಿನ ನೀರಿನಂತೆ. ಪಾತ್ರೆ ಅಲ್ಲಾಡಿದರೆ ಮನಸ್ಸೆಂಬ ನೀರಿನಲ್ಲಿ ಅಲೆಗಳು ಮೂಡುತ್ತವೆ. ಇದರಿಂದ\nಏಕಾಗ್ರತೆಗೆ ಭಂಗವಾಗುತ್ತದೆ.\n\nದೇಹದಲ್ಲಿ ಇನ್ನೊಂದು ಪ್ರಮುಖ ಅಂಗ ಕಣ್ಣು. ದೇಹವನ್ನು ಸ್ಥಿರಗೊಳಿಸಿದ ಮೇಲೆ ಕಣ್ಣನ್ನು ಸ್ಥಿರಗೊಳಿಸಬೇಕು.\nಮೂಗಿನ ತುದಿಯಲ್ಲಿ ದೃಷ್ಟಿಯನ್ನು ನೆಟ್ಟು ಯಾವ ದಿಕ್ಕಿನ ಯಾವ ಆಕೃತಿಯೂ ಕಾಣದಂತೆ ನೇರವಾಗಿ ಒಂದೇ\nಕಡೆ ದೃಷ್ಟಿ ಸ್ಥಿರಗೊಳಿಸಬೇಕು.(ಕಣ್ಣನ್ನು ಮುಚ್ಚಿ ಧ್ಯಾನ ಮಾಡಬಹುದು, ಆದರೆ ಕಣ್ಣನ್ನು ಮುಚ್ಚಿದರೆ ನಿದ್ದೆ\nಮಾಡುವ ಸಾಧ್ಯತೆ ಹೆಚ್ಚು).\n\nಈ ರೀತಿ ಧ್ಯಾನದ ಸ್ಥಿತಿಯನ್ನು ತಲುಪಿದಾಗ ಮನಸ್ಸು ಪ್ರಶಾಂತವಾಗುತ್ತದೆ. ಯಾವ ಗೊಂದಲವೂ ಇಲ್ಲದ\nಹೇಳಲಾಗದ ವಿಚಿತ್ರ ಆನಂದದಸ್ಥಿತಿಯನ್ನು ನಾವು ಈ ಸ್ಥಿತಿಯಲ್ಲಿ ಅನುಭವಿಸುತ್ತೇವೆ. ಇದರಿಂದ ನಮಗೆ ಎಲ್ಲಾ\nಭಯವೂ ಹೊರಟು ಹೋಗುತ್ತದೆ. ಧ್ಯಾನಕ್ಕೆ ಅತಿಮುಖ್ಯವಾಗಿ ಬೇಕಾದ ಇನ್ನೊಂದು ಅಂಶ ಬ್ರಹ್ಮಚರ್ಯ\nಪಾಲನೆ. ಇಲ್ಲಿ ಬ್ರಹ್ಮಚರ್ಯ ಎನ್ನುವ ಪದಕ್ಕೆ ಮೂರು ಅರ್ಥವಿದೆ. ಪರಬ್ರಹ್ಮನ ಕಡೆಗೆ ಹೋಗುವ ಧೀಕ್ಷೆ-\nಬ್ರಹ್ಮಚರ್ಯ; ನಿರಂತರ ವೇದಾಧ್ಯಯನ-ಬ್ರಹ್ಮಚರ್ಯ; ಸಂಸಾರಿಗಳಾದವರು. ನಿಯಮಿತ ಲೈಂಗಿಕತೆ\nಪಾಲಿಸುವುದು [ಅತಿ ಸುಲಭವಾಗಿ ಲೈಂಗಿಕತೆಯಿಂದ ದೂರ ಸರಿದು ನಿಲ್ಲುವ ಕ್ಷಮತೆ ಹಾಗೂ ನಿಯಮಿತ\nಲೈಂಗಿಕತೆ] ಹಾಗೂ ವಿರಕ್ತಿಗಳ(ನೈಷ್ಠಿಕ ಬ್ರಹ್ಮಚಾರಿ) ಲೈಂಗಿಕ ಮುಕ್ತ ಜೀವನ-ಬ್ರಹ್ಮಚರ್ಯ. ಭಗವಂತನೇ\nಸರ್ವೋತ್ತಮ ಎನ್ನುವ ಅಚಲವಾದ ಭಕ್ತಿಯಿಂದ, ಭಗವಂತನಲ್ಲಿ ಸಂಪೂರ್ಣ ಭರವಸೆಯನ್ನಿಟ್ಟು ಸದಾ\nಭಗವಂತನನ್ನು ನೆನೆಯುತ್ತಾ, ಎಂದೂ ಎದೆಗುಂದದೆ ಸಮಾಧಿಯನ್ನು ಸಾಧಿಸಬೇಕು.\n\nಧ್ಯಾನದ ಪರಿಣಾಮವೇನು? ನಾವು ಏಕೆ ಧ್ಯಾನ ಮಾಡಬೇಕು? ಉತ್ತರ ಮುಂದಿನ ಶ್ಲೋಕ!\n\nಮುಂದಿನ ಶ್ಲೋಕವನ್ನು ವಿಶ್ಲೇಷಿಸುವ ಮೊದಲು ಇಲ್ಲಿ ಸಾಮಾನ್ಯವಾಗಿ ಎಲ್ಲರಿಗೂ ಕಾಡುವ ಒಂದು\nಸರ್ವೇಸಾಮಾನ್ಯ ಪ್ರಶ್ನೆಯನ್ನು ವಿಶ್ಲೇಷಿಸೋಣ. ಯುದ್ಧರಂಗದಲ್ಲಿ ನಿಂತ ಅರ್ಜುನನಿಗೆ ಕೃಷ್ಣ ಭಗವದ್ಗೀತೆ\nಉಪದೇಶ ಮಾಡಿದ. ಹೀಗಿರುವಾಗ ಆತ ಧ್ಯಾನದ ಬಗ್ಗೆ, ಧ್ಯಾನ ಸಮಾಧಿಯ ಬಗ್ಗೆ, ಧ್ಯಾನಕ್ಕೆ ಕುಳಿತುಕೊಳ್ಳುವ\nವಿಧಾನದ ಬಗ್ಗೆ ಏಕೆ ಪ್ರಸ್ತಾಪಿಸಿದ? ಇದರ ಅಗತ್ಯವೇನಿತ್ತು? ಇದು ಸಾಮಾನ್ಯವಾಗಿ ಎಲ್ಲರನ್ನೂ ಕಾಡುವ ಪ್ರಶ್ನೆ.\nನಿಜವಾಗಿ ನೋಡಿದರೆ ಅರ್ಜುನನಿಗೆ ಈ ಪ್ರಶ್ನೆಗಳಿರಲಿಲ್ಲ, ಅರ್ಜುನನ ಪ್ರಶ್ನೆಯೇ ಬೇರೆ. ಆ ಪ್ರಶ್ನೆಗೆ ಉತ್ತರ\nಕೊಡುವಾಗ ಧ್ಯಾನದ ಪ್ರಶ್ನೆ ಸಾಮಾನ್ಯವಾಗಿ ಬಂದಾಗ, ಕೃಷ್ಣ ಇಡೀ ನರಸಮುದಾಯಕ್ಕೆ ಸಹಾಯವಾಗುವಂತೆ\nಸಂಪೂರ್ಣ ಧ್ಯಾನದ ಪ್ರಕ್ರೀಯೆಯನ್ನು ವಿವರಿಸಿದ. ಕೃಷ್ಣ ಯುದ್ಧರಂಗದಲ್ಲಿ ಅದೆಷ್ಟು ಸೂಕ್ಷ್ಮವಾಗಿ ಅರ್ಜುನನಿಗೆ ಈ\nಬೋಧನೆ ಮಾಡಿದ್ದನೋ ನಮಗೆ ತಿಳಿಯದು. ಆದರೆ ವ್ಯಾಸ ಮಹರ್ಷಿಗಳು ಇದನ್ನು ಎಳೆ ಎಳೆಯಾಗಿ ಬಿಡಿಸಿ\nಒಂದು ಅಧ್ಯಾಯ ರೂಪದಲ್ಲಿ ನಮಗೆ ಉಣಬಡಿಸಿದ್ದಾರೆ. ಭಗವದ್ಗೀತೆಯನ್ನು ಅರ್ಜುನನಿಗೆ ಉಪದೇಶ\nಮಾಡುವಾಗ ಕೃಷ್ಣನ ಮುಂದಿದ್ದದ್ದು ಕೇವಲ ಅರ್ಜುನ ಮಾತ್ರವಲ್ಲ; ಸಮಸ್ತ ಸಾತ್ವಿಕ ನರ ಸಮುದಾಯ. ಸರ್ವ\nಸಾತ್ವಿಕರಿಗೂ ಸತ್ಯದ ದಾರಿಯನ್ನು ತೋರಿಸುವ ಉದ್ದೇಶದಿಂದ ಗೀತೆಯ ಉಪದೇಶವಾಯಿತು. ಇದೇ ಮೂಲ\nಉದ್ದೇಶದಿಂದ ಶ್ರೀಕೃಷ್ಣ ಗೀತೆಯನ್ನು ಇನ್ನೊಮ್ಮೆ ಉದ್ದವನಿಗೆ ಉಪದೇಶ ಮಾಡಿದ್ದನ್ನು ನಾವಿಲ್ಲಿ ಸ್ಮರಿಸಬಹುದು.",
  "6.15": "ಯುಂಜನ್‌ ಏವಮ್‌ ಸದಾ ಆತ್ಮಾನಮ್‌ ಯೋಗೀ ನಿಯತ ಮಾನಸಃ |\n\nಶಾಂತಿಮ್‌ ನಿರ್ಬಾಣ ಪರಮಾಮ್‌ ಮತ್‌ ಸಂಸ್ಥಾಮ್‌ ಅಧಿಗಚ್ಛತಿ - ಹೀಗೆ ಭಗವಂತನನ್ನು ಸದಾ\nಧ್ಯಾನಿಸುತ್ತಾ, ಬಗೆಯನ್ನು ಬಿಗಿ ಹಿಡಿದ ಸಾಧಕನು ದೇಹ ತೊರೆದ ಮೇಲೆ ನನ್ನಲ್ಲೇ ನೆಲೆಸುವಂತಹ ಸುಖವನ್ನು\nಅನುಭವಿಸುತ್ತಾನೆ.\n\nಈ ಅಧ್ಯಾಯದಲ್ಲಿ ಈವರೆಗೆ ಕೃಷ್ಣ ವಿವರಿಸಿದ್ದು ಮನಸ್ಸಿನಿಂದ ಮಾಡುವ ಧ್ಯಾನ. ಬಾಹ್ಯ ಇಂದ್ರಿಯವನ್ನು\nಸ್ಥಬ್ಧಗೊಳಿಸಿ, ಚಿತ್ತ ಮತ್ತು ಮನಸ್ಸನ್ನು ನಿಯಂತ್ರಿಸಿ ಮಾಡುವುದು ಧ್ಯಾನ. ಇದರಿಂದಾಚೆಗಿರುವುದು\n'ತುರಿಯಾವಸ್ಥೆ'. ನಮ್ಮ ಮನಸ್ಸನ್ನು ಸಂಪೂರ್ಣ ಸ್ಥಬ್ಧಗೊಳಿಸಿ ಆತ್ಮಸ್ವರೂಪಭೂತವಾದ ಜೀವ ನೇರವಾಗಿ\nಭಗವಂತನನ್ನು ನೋಡುವ ಸ್ಥಿತಿ ತುರಿಯಾವಸ್ಥೆ. ಈ ಶ್ಲೋಕದಲ್ಲಿ ಕೃಷ್ಣ ತುರಿಯಾವಸ್ಥೆಯ ಸುಳಿವು ಕೊಡುತ್ತಾನೆ.\nಈ ವಿಚಾರ ಇಲ್ಲಿ ನಿಗೂಢವಾಗಿ ಅಡಗಿದೆ.\n\nಧ್ಯಾನದಲ್ಲಿ ನಾವು ಕಾಣುವುದು ನೇರ ಭಗವಂತನನ್ನಲ್ಲ ಬದಲಿಗೆ ಭಗವಂತನ ಪ್ರತೀಕವನ್ನು. ಏಕೆಂದರೆ ಮನಸ್ಸು\nನೇರವಾಗಿ ಜ್ಞಾನಾನಂದಸ್ವರೂಪಭೂತನಾದ ಭಗವಂತನನ್ನು ಗ್ರಹಿಸಲಾರದು. ಭಗವಂತನ ನೇರ\nದರ್ಶನವಾಗಬೇಕಾದರೆ, ಧ್ಯಾನದಿಂದಾಚೆಗಿನ ತುರಿಯಾವಸ್ಥೆಗೆ ಹೋಗಬೇಕು. ಜೀವಸ್ವರೂಪದ ಕಣ್ಣಿನಿಂದ\nಭಗವಂತನನ್ನು ಕಾಣಬೇಕು. ಮನಸ್ಸನ್ನು ನಿರಂತರವಾಗಿ ಭಗವಂತನಲ್ಲಿ ನೆಲೆಗೊಳಿಸಿ, ಮನಸ್ಸಿನ ಮೂಲಕ\nಧ್ಯಾನದಲ್ಲಿ ಭಗವಂತನ ಮಾನಸ ರೂಪ ಗೋಚರವಾದ ಮೇಲೆ ಮನಸ್ಸನ್ನು ಸ್ಥಬ್ಧಗೊಳಿಸಬೇಕು. ಆಗ\n\nತುರಿಯಾವಸ್ಥೆ ಜಾಗೃತವಾಗುತ್ತದೆ. ಈ ಹಂತದಲ್ಲಿ ಆತ್ಮ ಸ್ವರೂಪಕ್ಕೆ ಭಗವಂತನ ಸಂಯೋಗವಾಗುತ್ತದೆ. ಆಗ\nಅದು ನೇರವಾಗಿ ಭಗವಂತನನ್ನು ಕಾಣಬಲ್ಲದು. ಈ ಸ್ಥಿತಿಯನ್ನು ತಲುಪಿದ ಧ್ಯಾನಯೋಗಿ ನಿಜವಾದ ಯೋಗಿ\nಎನಿಸುತ್ತಾನೆ.\n\nಒಂದು ಜೀವ ತನ್ನ ಸಾಧನೆಯ ಹಾದಿಯಲ್ಲಿ ಪಡೆಯಬಹುದಾದ ಅತ್ಯಂತ ಮಹತ್ತರವಾದ ಆನಂದದ ಪರಾಕಾಷ್ಠೆ-\nಭಗವಂತನ ಸಾಕ್ಷಾತ್ಕಾರ. ಇದಕ್ಕಿಂತ ಮಿಗಿಲಾದ ಅರಿವು, ಆನಂದದ ದರ್ಶನ ಇನ್ನೊಂದಿಲ್ಲ. ಈ ರೀತಿ\nಭಗವಂತನ ಸಾಕ್ಷಾತ್ಕಾರವಾದವನು ಮುಂದೆಂದೂ ಈ ಸಂಸಾರ ಬಂಧದಲ್ಲಿ ಸಿಲುಕುವುದಿಲ್ಲ. ಆತ\nಭಗವಂತನಲ್ಲೇ ನೆಲೆಸಿ ಮೋಕ್ಷವನ್ನು ಪಡೆಯುತ್ತಾನೆ.\n\nಸಮಾಧಿಯನ್ನು ಅಭ್ಯಾಸ ಮಾಡುವವರ ಜೀವನಕ್ರಮ ಹೇಗಿರಬೇಕು ಎನ್ನುವುದನ್ನು ಕೃಷ್ಣ ಮುಂದೆ\nವಿವರಿಸುತ್ತಾನೆ. ಈ ಜೀವನಕ್ರಮ ಕೇವಲ ಧ್ಯಾನಕ್ಕೆ ಮಾತ್ರ ಪೂರಕವಲ್ಲ. ನಮ್ಮ ಅಧ್ಯಯನಕ್ಕೆ, ನಮ್ಮ\nಆರೋಗ್ಯ ಜೀವನಕ್ಕೆ ಈ ಶಿಸ್ತು ಬಹಳ ಮುಖ್ಯ. ನಮ್ಮ ಪ್ರತಿಯೊಂದು ಅನುಷ್ಠಾನವನ್ನು ಶಾಸ್ತ್ರಕಾರರು\nಇದಕ್ಕನುಗುಣವಾಗಿಯೇ ವಿನ್ಯಾಸ ಮಾಡಿದ್ದಾರೆ. ಆದರೆ ಇಂದು ನಮಗೆ ಈ ಎಐಎಚ್ಚರವಿಲ್ಲ. ಏಕಾದಶಿ\nಉಪವಾಸವಿರಲಿ, ಇನ್ಯಾವುದೇ ಅನುಷ್ಠಾನವಿರಲಿ, ಅದನ್ನು ಧ್ಯಾನಕ್ಕೆ ಪೂರಕವಾಗಿ ಪಾಲಿಸಬೇಕು. ಈ\nಜ್ಞಾನವಿಲ್ಲದೆ. ಕೇವಲ ಯಾಂತ್ರಿಕವಾಗಿ. ಪಾಲಿಸುವ ಯಾವ ಅನುಷ್ಠಾನವೂ ನಮ್ಮನ್ನು ಎತ್ತರಕ್ಕೆ\n\nಕೊಂಡೊಯ್ಯಲಾರದು.",
  "6.16": "ನ ಅತಿ ಅಶ್ಚತಃ ತು ಯೋಗಃ ಅಸ್ತಿ ನ ಚ ಅತ್ಯಂತಮ್‌ ಅನಶ್ನತಃ |\nನಚ ಅತಿ ಸ್ವಪ್ನ ಶೀಲಸ್ಯ ಜಾಗ್ರತಃ ನ ಏವ ಚ ಅರ್ಜುನ- ಹೇ ಅರ್ಜುನಾ, ಹೊಟ್ಟೆ ಬಾಕನಿಗೆ ಧ್ಯಾನಯೋಗ\nಸಾಧ್ಯವಿಲ್ಲ. ತೀರಾ ತಿನ್ನ ದವನಿಗೂ ಇಲ್ಲ. ತುಂಬಾ ತೂಕಡಿಸುವವನಿಗೂ ಇಲ್ಲ. ನಿದ್ದೆಗೇಡಿಗೂ ಇಲ್ಲ.\n\nಅತಿಯಾಗಿ ತಿನ್ನುವವನಿಗೆ ಧ್ಯಾನ ಸಾಧ್ಯವಿಲ್ಲ. ಹೊಟ್ಟೆಗೆ ಹೆಚ್ಚು ಆಹಾರ ಹೋದಾಗ ಮನಸ್ಸು ನಿಸ್ತೇಜವಾಗುತ್ತದೆ.\nಆದ್ದರಿಂದ ಮನನಶೀಲ ಹೊಟ್ಟೆಬಾಕನಾಗಿರಬಾರದು. ಅತಿಯಾದ ಆಹಾರ ಸೇವನೆ ಒಳ್ಳೆಯದಲ್ಲ. ಈ\nಕಾರಣಕ್ಕಾಗಿ ಅತಿಥಿ ಸತ್ಕಾರದಲ್ಲಿ ಒತ್ತಾಯ ಮಾಡಿ ಬಡಿಸುವುದು ತಪ್ಪು. ಅದೇ ರೀತಿ ಯಾವಾಗಲೂ ಸರಿಯಾಗಿ\nತಿನ್ನದೇ ಇದ್ದರೆ ಅದರಿಂದ ದೇಹ ಪೋಷಣೆ ಇಲ್ಲವಾಗಿ ದೇಹ ಕುಸಿಯುತ್ತದೆ. ಭಗವಂತನ\nಸಾಕ್ಷಾತ್ಮಾರವಾಗುವುದು ಈ ದೇಹದ ಮೂಲಕವೇ. ಆದ್ದರಿಂದ ನಾವು ನಿಯತವಾದ ಆಹಾರವನ್ನು ನಿಯತ\nಕಾಲದಲ್ಲಿ ತಿನ್ನು ವ ಅಭ್ಯಾಸ ಮಾಡಿಕೊಳ್ಳಬೇಕು.\n\nಆಹಾರದ ಜೊತೆಗೆ ನಮ್ಮ ನಿದ್ದೆ ಮಾಡುವ ಅಭ್ಯಾಸ ನಿಯತವಾಗಿರಬೇಕು. ನಾವು ಹೇಗೆ ಅಭ್ಯಾಸ\nಮಾಡಿಕೊಂಡೆವೋ ಹಾಗೇ ನಮ್ಮ ಮನಸ್ಸು . ಎಂದೂ ಅತಿನಿದ್ದೆ ಒಳ್ಳೆಯದಲ್ಲ. ಅದೇ ರೀತಿ ನಿದ್ದೆಗೆಟ್ಟ ರೆ ಖಂಡಿತ\n\nಧ್ಯಾನ ಸಾಧ್ಯವಿಲ್ಲ. ನಿಯತವಾದ ಆಹಾರ ನಿದ್ದೆ ನಮ ಹ ಆರೋಗ್ಯಕ್ಕೂ ಪೂರಕ ಹಾಗೂ ಧ್ಯಾನಕ್ಕೆ ಅತ್ಯಗತ್ಯ.\n",
  "6.17": "ಯುಕ್ತ ಆಹಾರ ವಿಹಾರಸ್ಯ ಯುಕ್ತ ಚೇಷ್ಟ ಸ್ಯ ಕರ್ಮಸು ।\nಯುಕ್ತ ಸ್ವಪ್ನ ಅವಬೋಧಸ್ಯ ಯೋಗಃ ಭವತಿ ದುಃಖ ಹಾ-- ತಕ್ಕ ತಿನಿಸು-ತಿರುಗಾಟ, ತಕ್ಕಷ್ಟೇ ಕಾಯಕ, ತಕ್ಕಂತೆ\nನಿದ್ದೆ-ಎಚ್ಚರ ಸಾಧಿಸಿದವನಿಗೆ ಧ್ಯಾನಯೋಗದಿಂದ ದುಗುಡ ದೂರ.\n\nಯೋಗಾಭ್ಯಾಸ ಮಾಡುವಾಗ ನಮ್ಮ ಜೀವನಕ್ರಮ ಶಿಸ್ತುಬದ್ಧವಾಗಿರಬೇಕು. ನಿಯಮಿತವಾದ ಹಾಗೂ\nಯೋಗ್ಯವಾದ ಆಹಾರ ಸೇವನೆ ಬಹಳ ಮುಖ್ಯ. ಧ್ಯಾನಕ್ಕೆ ಮನಸ್ಸ ನ್ನು ಅಣಿಗೊಳಿಸುವ ಸಾತ್ವಿಕ ಆಹಾರ ಸೇವನೆ\nಧ್ಯಾನಕ್ಕೆ ಪೂರಕ. ಕೆಲವು ಆಹಾರ ನಮ್ಮ ಮನಸ್ಸಿನ ಮೇಲೆ ಕೆಟ್ಟ ಪರಿಣಾಮ ಬೀರುತ್ತದೆ. ಉದಾಹರಣೆಗೆ\nಈರುಳ್ಳಿ ಮತ್ತು ಬೆಳ್ಳುಳ್ಳಿ. ಇವುಗಳಲ್ಲಿ ಔಷಧೀಯ ಗುಣವಿದ್ದರೂ ಕೂಡಾ ಇದು ನಮ್ಮ ಮನಸ್ಸಿನ ಮೇಲೆ\nಪರಿಣಾಮ ಬೀರುವ ಆಹಾರ. ನಾವು ಈರುಳ್ಳಿ ಅಥವಾ ಬೆಳ್ಳುಳ್ಳಿಯನ್ನು ಅತಿಯಾಗಿ ಸೇವಿಸಿದ ದಿನ ನಮಗೆ ಕೆಟ್ಟ\nಕನಸು ಬೀಳುವುದು ಈ ಆಹಾರ ಮನಸ್ಸಿನ ಮೇಲೆ ಪ್ರಭಾವ ಬೀರುತ್ತದೆ ಎನ್ನುವುದಕ್ಕೆ ಪುರಾವೆ[ಆದರೆ ವೈದ್ಯರು\nಆರೋಗ್ಯ ದೃಷ್ಟಿಯಿಂದ ಇದನ್ನು ಔಷಧವಾಗಿ ಸೇವಿಸಲು ಹೇಳಿದರೆ ಆಗ ತಿನ್ನುವುದರಲ್ಲಿ ಯಾವ ತೊಂದರೆಯೂ\nಇಲ್ಲ. ಏಕೆಂದರೆ ಅಧ್ಯಯನಕ್ಕೆ ಮೊತ್ತಮೊದಲು ಆರೋಗ್ಯ ಬೇಕು]. ವೇದಾಧ್ಯಾಯನ ಮಾಡುವವರು ಇಂತಹ\nಮನಸ್ಸನ್ನು ಕೆಡಿಸುವ ಆಹಾರವನ್ನು ಸೇವಿಸಬಾರದು. ನಮ್ಮ ದೇಹದ ಪೋಷಣೆಯ ಜೊತೆಗೆ ನಮ್ಮ ಮನಸ್ಸಿಗೆ\nಸಾತ್ವಿಕ ಪೋಷಣೆ ಕೊಡುವ ಆಹಾರವನ್ನು ಇಲ್ಲಿ ಕೃಷ್ಣ “ಯುಕ್ತಾಹಾರ” ಎಂದು ಕರೆದಿದ್ದಾನೆ.\n\nನಮ್ಮ ಮನಸ್ಸಿಗೆ ನಾವು ಎಷ್ಟು ಬೇಕೋ ಅಷ್ಟು ವಿರಾಮ ಕೊಡುವುದು ಬಹಳ ಮುಖ್ಯ. ಆದರೆ ಈ ವಿರಾಮ\nಸೋಮಾರಿತನವಾಗಿ ರೂಪುಗೊಳ್ಳಬಾರದು. ಮನಸ್ಸಿಗೆ ವಿರಾಮ ಕೊಡುವಾಗ ಯಾವ ಚಿಂತನೆ ಕೂಡಾ\nಮಾಡದೆ ಸಂಪೂರ್ಣ ವಿಶ್ರಾಂತಿಯನ್ನು ಕೊಡಬೇಕು. ಆಗ ಮನಸ್ಸು ಧ್ಯಾನಕ್ಕೆ ಪೂರಕವಾಗಿ ಕೆಲಸ ಮಾಡುತ್ತದೆ.\n“ಯುಕ್ತಚೇಷ್ಟಸ್ಯ ಕರ್ಮಸು” ನಾವು ಮಾಡಬೇಕಾದ ಕೆಲಸ ಕಾರ್ಯವನ್ನು ಕ್ರಮಬದ್ಧವಾಗಿ ಪ್ರಮಾಣಬದ್ಧವಾಗಿ\nನಾವೇ ಮಾಡಬೇಕು. ಮಾಡಬೇಕಾದ ಕೆಲಸದಲ್ಲಿ ಸೋಮಾರಿತನವಿರಬಾರದು.\n\nಶಾಸ್ತ್ರೀಯವಾದ ಶುದ್ಧವಾದ ಕ್ರಮಬದ್ಧವಾದ ಆಹಾರ ಸೇವನೆ, ತಕ್ಕ ಕಾಲದಲ್ಲಿ ತಕ್ಕಷ್ಟು ನಿದ್ದೆ ಹಾಗೂ ಎಚ್ಚರ,\nಕ್ರಮಬದ್ಧವಾದ ಪರಿಶ್ರಮ ಮತ್ತು ವಿರಾಮ- ಹೀಗೆ ಇದ್ದಾಗ “ಯೋಗೋ ಭವತಿ ದುಃಖಹಾ”- ದುಃಖ ರಹಿತ\nಆನಂದಮಯ ಜೀವನ ಸಾಧ್ಯ.\n\nಧ್ಯಾನಯೋಗದಿಂದ ಮನಸ್ಸು ಒಂದು ಹದಕ್ಕೆ ಬರುತ್ತದೆ. ಮನಸ್ಸು ಹದವಾದಾಗ ಹೊರಪ್ರಪಂಚದಲ್ಲಿ ನಾವು\nಅನುಭವಿಸುವ ಸುಖ-ದುಃಖಗಳನ್ನೂ ನಿರ್ಲಿಪ್ರವಾಗಿ ನೋಡಲು ಅಭ್ಯಾಸವಾಗುತ್ತದೆ. ಇದರಿಂದ ಸುಖ ಬಂದಾಗ\nಹಾರಾಟವಿಲ್ಲ, ದುಃಖ ಬಂದಾಗ ಪಾತಾಳಕ್ಕೆ ಕುಸಿಯುವುದೂ ಇಲ್ಲ. ಸುಖ-ದುಃಖ, ಸೋಲು-ಗೆಲುವಿನ ದ್ವಂದ್ವವೇ\nಜೀವನ ಎನ್ನುವ ಸಮದೃಷ್ಟಿ ಧ್ಯಾನಯೋಗದಿಂದ ಬಂದುಬಿಡುತ್ತದೆ.",
  "6.18": "ಯದಾ ವಿನಿಯತಮ್‌ ಚಿತ್ತಮ್‌ ಆತ್ಮನಿ ಏವ ಅವತಿಷ್ಠತೇ ।\nನಿಸೃಹಃ ಸರ್ವ ಕಾಮೇಭ್ಯಃ ಯುಕ್ತಃ ಇತಿ ಉಚ್ಯತೇ ತದಾ-ಚೆನ್ನಾ ಗಿ ಹದಗೊಂಡ ಒಳಬಗೆ ಭಗವಂತನಲ್ಲೇ\nನೆಲೆಗೊಂಡಾಗ, ಎಲ್ಲಾ ಕಾಮಗಳ ಆಸೆ ಅಳಿದಾಗ 'ಧ್ಯಾನಯೋಗಿ' ಎನ್ನಿ ಸಿಕೊಳ್ಳುತ್ತಾನೆ.\n\nಯೋಗಾಭ್ಯಾಸದಿಂದ ಯೋಗಿಯ ಸುಪ್ಪಪ್ರಜ್ಞೆ ನಿಯಂತ್ರಣವಾಗುತ್ತದೆ. ಸಾಮಾನ್ಯವಾಗಿ ನಮ್ಮ ಚಿತ್ತದಲ್ಲಿರುವ\nಹಿಂದಿನ ಕೆಟ್ಟ ನೆನಪುಗಳು ಸದಾ ನಮ್ಮನ್ನು ಕಾಡುತ್ತಿರುತ್ತವೆ. ಯಾವುದೋ ಹಗೆ, ಯಾವುದೋ ಪ್ರೀತಿ\nಇವೆಲ್ಲವನ್ನೂ ಬದಿಗೊತ್ತಿ ಯೋಗಿ ತನ್ನ ಅಂತರಂಗದ ಪೀಠದಲ್ಲಿ ಕೇವಲ ಭಗವಂತನನ್ನು ಕೂರಿಸಬಲ್ಲ. ಹೀಗೆ\nಮಾಡಿದಾಗ ಸದಾ ಅಂತರಂಗದಲ್ಲಿ ಭಗವಂತನ ದರ್ಶನವಾಗುತ್ತದೆ. ಆ ಭಗವಂತನನ್ನು ಕಂಡಮೇಲೆ ಇನ್ನೇನೂ\nಬೇಕು ಎನಿಸುವುದಿಲ್ಲ. ಏಕೆಂದರೆ ಭಗವಂತ ನಾವು ಬಯಸುವ ಸಂಗತಿಗಳಲ್ಲೇ ಅತ್ಯಂತ ಶ್ರೇಷ್ಠವಾದ ಸಂಗತಿ.\nಅಂತರಂಗದ ಆನಂದದ ಚಿಲುಮೆ ತೆರೆದುಕೊಂಡಾಗ ಕ್ಷುದ್ರವಾದ ಬಾಹ್ಯ ಕಾಮನೆಗಳು ಅಳಿದುಹೋಗಿ ಆತ\nಧ್ಯಾನಯೋಗಿ ಎನಿಸಿಕೊಳ್ಳುತ್ತಾನೆ.\n",
  "6.19": "ಯಥಾ ದೀಪಃ ನಿವಾತಸ್ಥಃ ನ ಇಂಗತೇ ಸಾ ಉಪಮಾ ಮತಾ ।\n\nಯೋಗಿನಃ ಯಶಚಿತ್ತಸ್ಯ ಯುಂಜತಃ ಯೋಗಮಾತ್ಮನಃ -ಗಾಳಿಯಿಲ್ಲದ ತಾಣದಲ್ಲಿರುವ ದೀಪ ಹಂದುವುದಿಲ್ಲ\nಹೇಗೋ ಹಾಗೆ ಇದು: ಒಳಬಗೆಯನ್ನು ಹದಗೊಳಿಸಿ ಭಗವಂತನನ್ನು ನೆನೆಯುವ ಧ್ಯಾನಯೋಗಿಗೆ ಇದು\nಉಪಮಾನ.\n\nಗಾಳಿ ಬೀಸದ ಸ್ಥಳದಲ್ಲಿ ಉರಿಯುವ ಬೆಂಕಿಯ ಶಿಖೆಯಂತೆ ಬಗೆಯನ್ನು ಹದಗೊಳಿಸಿದ ಯೋಗಿಯ ಮನಸ್ಸಿನಲ್ಲಿ,\n“ಭಗವಂತನ ಕುರಿತಾದ ಮನಸ್ಸಿನ ಯೋಗ(ಆತ್ಮಯೋಗ)' ನಿಶ್ಚಲವಾಗಿರುತ್ತದೆ. ಅದು ಚಲಿಸುವುದಿಲ್ಲ.\n",
  "6.20": "ಯತ್ರ ಉಪರಮತೇ ಚಿತ್ತಮ್‌ ನಿರುದ್ಧಮ್‌ ಯೋಗ ಸೇವಯಾ।\n\nಯತ್ರ ಚ ಏವ ಆತ್ಮನಾ ಆತ್ಮಾನಮ್‌ ಪಶ್ಯನ್‌ ಆತ್ಮನಿ ತುಷ್ಯತಿ ॥|",
  "6.21": "ಸುಖಮ್‌ ಆತ್ಯನ್ಪಿಕಮ್‌ ಯತ್‌ ತತ್‌ ಬುದ್ಧಿ ಗ್ರಾಹ್ಯಮ್‌ ಅತೀಂದ್ರಿಯಮ್‌ |\nವೇತ್ತಿ ಯತ್ರ ನ ಚ ಏವ ಅಯಮ್‌ ಸ್ಥಿತಃ ಚಲತಿ ತತ್ತ್ವತಃ |",
  "6.22": "ಯಮ್‌ ಲಬ್ಧ್ವಾ ಚ ಅಪರಮ್‌ ಲಾಭಮ್‌ ಮನ್ಯತೇ ನ ಅಧಿಕಮ್‌ ತತಃ ।\nಯಸ್ಮಿನ್‌ ಸ್ಥಿತಃ ನ ದುಃಖೇನ ಗುರುಣಾ ಅಪಿ ವಿಚಾಲ್ಯತೇ ॥\n",
  "6.23": "ತಮ್‌ ವಿದ್ಯಾತ್‌ ದುಃಖಸಂಯೋಗ ವಿಯೋಗಮ್‌ ಯೋಗಸಂಜ್ಜಿತಮ್‌ |\nಸಃ ನಿಶ್ಚಯೇನ ಯೋಕ್ತವ್ಯಃ ಯೋಗಃ ಅನಿರ್ವಿಣ್ಣಚೇತಸಾ ॥\n\nಧ್ಯಾನ ಸಾಧನೆಯಿಂದ ಬಿಗಿಗೊಂಡ ಒಳಬಗೆ ಈ ಸ್ಥಿತಿಯಲ್ಲಿ ಹೊರಗಣ ವಿಷಯಗಳತ್ತ ಹರಿಯದು. ಇಲ್ಲಿ\nತನ್ನೊಳಗೆಯೇ ಬಗೆಯಿಂದ[ಭಗವಂತನ ಹಸಾದದಿಂದ] ಭಗವಂತನನ್ನು ಕಾಣುತ್ತಾ ಸಂತಸಗೊಳ್ಳುತ್ತಾನೆ.ಇಲ್ಲಿ\nಇಂದ್ರಿಯಗಳಿಂದ ದೊರಕದ, ಒಳಬಗೆಯಲ್ಲಿ ಅರಳುವ ಅತಿಶಯವಾದ ಆನಂದವನ್ನು ಅನುಭವಿಸುತ್ತಾನೆ. ಈ\nಸ್ಥಿತಿಯಲ್ಲಿ ನಿಂತವನು ಎಂದೂ ಭಗವಂತನಿಂದ ಕದಲುವುದಿಲ್ಲ. ಇದನ್ನು ಪಡೆದ ಮೇಲೆ ಇನ್ಯಾವ ಗಳಿಕೆಯೂ\nಇದಕ್ಕಿಂತ ಮಿಗಿಲೆನಿಸುವುದಿಲ್ಲ. ಇಲ್ಲಿ ನಿಂತವನು ಎಂತಹ ಹಿರಿಯ ದುಗುಡದಿಂದಲೂ ಕಂಗೆಡುವುದಿಲ್ಲ. ಇದೇ\nಎಲ್ಲಾ ದುಗುಡಗಳಿಂದ ಬಿಡುಗಡೆಗೊಳಿಸುವ ಯೋಗವೆಂದರಿಯಬೇಕು. ವಿಷಯಗಳಿಂದ ಬೇಸತ್ತು ಬೆನ್ನು\nತಿರುಗಿಸಿದವನು ಅವಶ್ಯವಾಗಿ ಈ ಯೋಗದಲ್ಲಿ ಪಳಗಬೇಕು.\n\nಹೊರಗಿನ ಪ್ರಪಂಚದ ಸಂಪರ್ಕವನ್ನು ಕಳೆದುಕೊಂಡು ಮನಸ್ಸು ಭಗವಂತನಲ್ಲಿ ನೆಲೆಸಿದಾಗ ಏನಾಗುತ್ತದೆ\nಎಂದರೆ- ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಉಪರಮತೇ ಚಿತ್ತಮ್‌” ಅಂದರೆ ಉತ್ಕೃಷ್ಟವಾದ ಆ ಆನಂದದಲ್ಲೇ ಮನಸ್ಸು\nನಿಂತುಬಿಡುತ್ತದೆ. ಆ ಆನಂದದ ಸೆಲೆಯಿಂದ ಬೇರೆಯಾಗುವುದು ಬೇಡ ಎನ್ನುವ ಭಾವನೆ ಬಂದುಬಿಡುತ್ತದೆ.\nಸಾಮಾನ್ಯವಾಗಿ ತಕ್ಷಣ ಈ ಸ್ಥಿತಿಗೆ ಮನಸ್ಸು ಹೋಗುವುದಿಲ್ಲ. ಅದಕ್ಕೆ ಬಹಳ ಪ್ರಯತ್ನ ಬೇಕು. ಪ್ರಯತ್ನ ಒಂದು\nಜನ್ಮದ್ದಲ್ಲ ಅನೇಕ ಜನ್ಮದ ಪ್ರಯತ್ನವಿಲ್ಲದೆ ಒಮ್ಮೆಗೇ ಈ ಸ್ಥಿತಿಯನ್ನು ತಲುಪುವುದು ಅಸಾಧ್ಯ. ನಿರಂತರ\nಯೋಗಾಭ್ಯಾಸದ ಸಾಧನೆಯಿಂದ ಚಿತ್ತವೃತ್ತಿಯನ್ನು ನಿರೋಧ ಮಾಡಬೇಕು. ಅಂದರೆ ನಮ್ಮ ಮನಸ್ಸನ್ನು\nತಡೆಹಿಡಿಯಬೇಕು. ಅದು ಎಲ್ಲಿಯೂ ಹರಿಯದಂತೆ ಒಡ್ಡುಹಾಕಿ ಅದು ಭಗವಂತನಲ್ಲೇ ನೆಲೆನಿಲ್ಲುವಂತೆ\nಮಾಡಬೇಕು.\n\nನಮಗೆ ಆತ್ಮಸಾಕ್ಷಾತ್ಕಾರವಾದಾಗ ಎಂದೂ ಆಗದ ಅಪೂರ್ವ ಆನಂದವಾಗುತ್ತದೆ. ಇದು ಅತ್ಯಂತ ಶ್ರೇಷ್ಠವಾದ\nಆನಂದದ ಅನುಭವ. ಭಗವಂತನ ಬಗ್ಗೆ ಭಕ್ತನ ಭಕ್ತಿ ಹಾಗೂ ಭಕ್ತನ ಮೇಲೆ ಭಗವಂತನ ವಾತ್ಸಲ್ಯ ಇವೆರಡೂ\nಮೇಳವಹಿಸಿದಾಗ 'ನಿರ್ಭಯ'. ಒಳಗಣ್ಣಿನಿಂದ ಧ್ಯಾನದ ಸ್ಥಿತಿಯಲ್ಲಿ ಅಂತರ್ಯಾಮಿಯಾದ ಭಗವಂತನನ್ನು\nಕಾಣುವುದು ಧ್ಯಾನದಲ್ಲಿ ಬರುವ ಅನುಭವ. ಇಲ್ಲಿ ನಮಗೆ ಕಾಣುವುದು ಮನಸ್ಸು ಕಡೆದ ಆ ಭಗವಂತನ ಭವ್ಯ\nರೂಪ. ಇದು ಕೇವಲ ಭಗವಂತನ ಪ್ರತೀಕ. ನಾವು ಭಗವಂತನನ್ನು ನಿಜವಾಗಿ ಕಾಣಬೇಕಾದರೆ ಅವನು\nನಮ್ಮನ್ನು ಪ್ರೀತಿಸಬೇಕು. ಭಗವದ್‌ ಅನುಗ್ರಹವಾದಾಗ ನಮ್ಮ ಸ್ವರೂಪ ಭಗವಂತನನ್ನು ಕಾಣುತ್ತದೆ. ಇದು\nಬಹಳ ಉತ್ಕಟವಾದ ಸ್ಥಿತಿ. ಈ ಸ್ಥಿತಿಯಲ್ಲಿ ಮನಸ್ಸು ಸಂಪೂರ್ಣ ಸ್ತಬ್ಧವಾಗಿ ನೇರವಾಗಿ ಆತ್ಮಸ್ವರೂಪ ತನ್ನ\nಆತ್ಮಸ್ವರೂಪದ ಕಣ್ಣಿನಿಂದ ಭಗವಂತನನ್ನು ಕಾಣುತ್ತದೆ. ಈ ಸ್ಥಿತಿ ಸಂಪೂರ್ಣ ತೃಪ್ತಿಯನ್ನು ಕೊಡಬಲ್ಲದು.\nಇಂದ್ರಿಯಗಳಿಂದ ಸಿಗುವ ಆನಂದ ಸಾಪೇಕ್ಷ ಎನ್ನುವ ನಿಜ ಆ ಹಂತದಲ್ಲಿ ತಿಳಿಯುತ್ತದೆ. ಈ ಉತ್ಕಟವಾದ\nಆನಂದವನ್ನು ಅನುಭವಿಸಿದ ಮೇಲೆ ಮತ್ತೆ ಮೇಲೇರಬೇಕು ಅಥವಾ ಕೆಳಗಿಳಿಯಬೇಕು ಎನ್ನು ವ ಬಯಕೆ ಇಲ್ಲ.\nಭಗವಂತನ ಪೂರ್ಣ ಅನುಭವ ಬಂದಾತ ಯಾವ ಪ್ರಾಪಂಚಿಕ ದುಃಖದಲ್ಲೂ ಎಂದೂ ವಿಚಲಿತನಾಗುವುದಿಲ್ಲ.\nಇದು ಮಾನವ ಜೀವನದಲ್ಲಿ ಪಡೆಯಬಹುದಾದ ಅತೀ ಎತ್ತರದ ಸ್ಥಿತಿ. ನಾವು ನಿಜವಾದ ಆನಂದವನ್ನು\nಕಾಣಬೇಕಾದರೆ ಈ ಉತ್ಕಟವಾದ ಸ್ಥಿತಿಯನ್ನು ತಲುಪಬೇಕು.\n\nಮೇಲೆ ಹೇಳಿದ ವಿಚಾರವನ್ನು ಕೇಳಿ ಕೆಲವರು ಭ್ರಮೆಗೊಳಗಾಗಿ ಒಮ್ಮೆಗೇ ಎಲ್ಲವನ್ನೂ ಬಿಟ್ಟು ಈ ಸ್ಥಿತಿಯನ್ನು\nತಲುಪುವ ಸಾಹಸಕ್ಕೆ ಕೈ ಹಾಕುತ್ತಾರೆ. ಆದರೆ ಹಾಗೆ ಮಾಡಿದರೆ ಎಂದೂ ಯಶಸ್ಸು ಸಿಗದು. ಕೇವಲ ನಿರಂತರ\nಸಾಧನೆಯಿಂದ ಮಾತ್ರ ಈ ಆನಂದವನ್ನು ಪಡೆಯಲು ಸಾಧ್ಯ. ಜೀವನದ ಸುಖವನ್ನು ಅನುಭವಿಸಿ, ಪ್ರಾಪಂಚಿಕ\nಸುಖ ಸಾಕು ಎಂದು ಕಾಣಿಸಿದಾಗ ಅಧ್ಯಾತ ದ ಆಳಕ್ಕಿಳಿಯುವ ಪ್ರಯತ್ನ ಮಾಡಬೇಕು. ಇಲ್ಲದಿದ್ದರೆ ಅಪಾಯ.\n\nಸಂಕಲ್ಪಪ್ರಭವಾನ್‌ ಕಾಮಾಂಸ್ಕಕ್ತ್ವಾ ಸರ್ವಾನಶೇಷತಃ ।\n\nಮನಸೈವೇ",
  "6.24": "ಶನೈಃ ಶನೈರುಪರಮೇದ್‌ ಬುದ್ಧ್ಯಾ ಧೃ",
  "6.25": "ಸಂಕಲ್ಪ ಪ್ರಭವಾನ್‌ ಕಾಮಾನ್‌ ತ್ಯಕ್ತ್ವಾ ಸರ್ವಾನ್‌ ಅಶೇಷತಃ ।\n\nಮನಸಾ ಏವ ಇಂದ್ರಿಯ ಗ್ರಾಮಮ್‌ ವಿನಿಯಮ್ಯ ಸಮಂತತಃ ॥\n\nಶನೈಃ ಶನೈಃ ಪರಮೇತ್‌ ಬುದ್ಧ್ವಾ ಧೃತಿ ಗೃಹೀತಯಾ ।\n\nಆತ್ಮಸಂಸ್ಥಮ್‌ ಮನಃ ಕೃತ್ವಾ ನ ಕಿಂಚಿತ್‌ ಅಪಿ ಚಿಂತಯೇತ್‌ -ಬಗೆಯಲ್ಲಿ ಮೂಡಿಬರುವ ಎಲ್ಲಾ ಬಯಕೆಗಳನ್ನೂ\nಪೂರ್ತಿಯಾಗಿ ತೊರೆದುಬಿಡಬೇಕು; ಇಂದ್ರಿಯಗಳ ಗಡಣವನ್ನು ಎಲ್ಲೆಡೆಯಿಂದಲೂ ಮನೋಬಲದಿಂದಲೇ\nಹಿಡಿತದಲ್ಲಿಡಬೇಕು; ಅಳುಕದ ವಿವೇಕ ಪ್ರಜ್ಞೆಯಿಂದ ಮೆಲ್ಲಮೆಲ್ಲನೆ ಬಗೆಯನ್ನು ವಿಷಯಗಳಿಂದ ಹೊರಳಿಸಬೇಕು;\nಭಗವಂತನಲ್ಲಿರಿಸಬೇಕು. ಇರಿಸಿ ಮತ್ತೇನನ್ನೂ ಚಿಂತಿಸಬಾರದು.\n\nಮನಸ್ಸನ್ನು ಭಗವಂತನಲ್ಲಿ ನೆಲೆಗೊಳಿಸುವ ವಿಧಾನವನ್ನು ಮತ್ತೆ ಕೃಷ್ಣ ಇಲ್ಲಿ ವಿವರಿಸುತ್ತಾನೆ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ:\n“ಸಂಕಲ್ಪ ಪ್ರಭವಾನ್‌ ಕಾಮಾನ್‌ ತ್ಯಕ್ತ್ವಾ ಸರ್ವಾನ್‌ ಅಶೇಷತಃ” ಎಂದು. ಇದರ ಹಿನ್ನೆ ಲೆಯನ್ನು ಹಿಂದೆ ನಾವು\nನೋಡಿದ್ದೇವೆ. ನಮ್ಮ ಎಲ್ಲಾ ಸಮಸ್ಯೆಗಳ ಮೂಲ ನಮ್ಮ ಸಂಕಲ್ಪಗಳು. ಸಂಕಲ್ಪಗಳು ಎಂದರೆ ಮನಸ್ಸಿನಲ್ಲಿ\nಏನೇನು ಮಾಡಬೇಕು ಎನ್ನುವ ತೀರ್ಮಾನ. ನಾವು ಯಾವುದೇ ಒಂದು ಕೆಲಸವನ್ನು ಮಾಡುವ ಮೊದಲು\nಅದನ್ನು ಮಾನಸಿಕವಾಗಿ ಮಾಡುತ್ತೇವೆ. ಇಂದು ಇಲ್ಲಿಗೆ ಹೋಗಬೇಕು, ಇಂತವರನ್ನು ಭೇಟಿಯಾಗಬೇಕು, ಅಲ್ಲಿ\nಇಂತಹದ್ದನ್ನು ಪಡೆಯಬೇಕು, ಇತ್ಯಾದಿ ವೇಳಾಪಟ್ಟಿ ನಮ್ಮ ಮನಸ್ಸಿನಲ್ಲಿ ನೆಟ್ಟಿರುತ್ತದೆ. ಈ ರೀತಿ ಸಾವಿರ\nಸಂಕಲ್ಪಗಳು, ಅದನ್ನು ಈಡೇರಿಸಿಕೊಳ್ಳುವುದಕ್ಕೆ ಸಾವಿರ ಬಯಕೆಗಳು. “ಹೀಗೆ ಮಾಡಬೇಕು ಅದರಿಂದ ಹೀಗೇ\nಆಗಬೇಕು ಎನ್ನುವ ಆಸೆಗಳು'. ಬದುಕು ಎಂದರೆ ನಾವು ನಮ್ಮ ಮನಸ್ಸಿನಲ್ಲಿ ಕಲ್ಪಿಸಿಕೊಂಡ ಬದುಕಿನ\nರೂಪುರೇಷೆಯನ್ನು ಬಾಹ್ಯ ಪ್ರಪಂಚದಲ್ಲಿ ಸಾಕಾರಗೊಳಿಸುವ ಪ್ರಯತ್ನ. ಹೀಗೆ ಸಾವಿರಾರು ಸಂಕಲ್ಪ ಮತ್ತು\nಕಾಮನೆಯನ್ನು ಮನಸ್ಸಿನಲ್ಲಿ ತುಂಬುತ್ತಾ ಹೋದರೆ ಮನಸ್ಸಿಗೆ ಅದರಿಂದಾಚೆಗೆ ಯೋಚಿಸಲು ಅವಕಾಶವೇ\nಇಲ್ಲವಾಗುತ್ತದೆ. ಮನಸ್ಸು ಎಂದರೆ ಬರೀ ಸಂಕಲ್ಪ-ವಿಕಲ್ಪ. ಏನೇನೋ ಕನಸು ಕಟ್ಟು ವುದು(ಸಂಕಲ್ಪ),\nಮಾಡಬೇಕೋ ಬೇಡವೋ, ಮಾಡಿದರೆ ಯಶಸ್ವಿ ಆದೀತೋ ಇಲ್ಲವೋ (ವಿಕಲ್ಪ) ಎಂದು ಯೋಚಿಸುತ್ತಾ\nಅದರಿಂದ ಗೊಂದಲಕ್ಕೊಳಗಾಗುವುದು. ಇದರಿಂದಾಚೆಗೆ ಮನಸ್ಸು ಹೋಗುವುದೇ ಇಲ್ಲ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ\n“ಮೊದಲು ನಿನ್ನ ಸಂಕಲ್ಪಗಳನ್ನು ಬಿಟ್ಟುಬಿಡು” ಎಂದು. ಈ ಸಂಕಲ್ಪಗಳು ತಿರುಕನ ಕನಸಿನಂತೆ. ಎಷ್ಟು ಹೆಚ್ಚು\nಸಂಕಲ್ಪ ನಮ್ಮ ಮನಸ್ಸಿಗೆ ಬರುತ್ತದೇ ಅಷ್ಟೇ ಹತಾಶೆ ಹೆಚ್ಚಾಗುತ್ತದೆ, ಅದರಿಂದ ವ್ಯಾಕುಲತೆ. ನಂತರ ಏನನ್ನೂ\nಯೋಚಿಸಲು ಆಗುವುದಿಲ್ಲ!\n\nಬಯಸುವುದು ಮನಸ್ಸಿ ನ ಸಹಜ ಗುಣ, ಬಯಸದೇ ಬದುಕಿಲ್ಲ. ಅದಕ್ಕಾಗಿ ಏನು ಬರುತ್ತದೋ ಅದು ಬರಲಿ\nಎಂದು ಬಯಸುವುದನ್ನು ಕಲಿತು ನಮ್ಮ ಇತರ ಸಂಕಲ್ಪ ವಿಕಲ್ಪವನ್ನು ಬಿಟ್ಟುಬಿಡಬೇಕು. ಇದು ಯಶಸ್ವಿನ ಸೂತ್ರ.\nಬಯಸಿದ್ದು ಸಿಗುವುದಿಲ್ಲ, ಬಯಸಿದಂತೆ ಆಗುವುದಿಲ್ಲ ಎಂದ ಮೇಲೆ ಅನಗತ್ಯ ಕನಸಿನ ಗೋಪುರ ಕಟ್ಟುವುದರಲ್ಲಿ\nಯಾವ ಅರ್ಥವೂ ಇಲ್ಲ. ನಮ್ಮ ಸಂಕಲ್ಪ ಕೇವಲ ಒಂದೇ ಒಂದು- “ಭಗವಂತನ ಸಂಕಲ್ಪ ಹೇಗೋ ಹಾಗೆ'.\nದ್ವಾದಶ ಸ್ತೋತ್ರದಲ್ಲಿ ಮಧ್ವಾಚಾರ್ಯರು ಹೇಳುವಂತೆ:\n\nಕುರು ಭುಂಕ್ಷ್ವ ಚ ಕರ್ಮ ನಿಜಂ ನಿಯತಂ ಹರಿಪಾದ ವಿನಮ್ರಧಿಯಾ ಸತತಂ |\n\nಹರಿರೇವ ಪರೋ ಹರಿರೇವ ಗುರುಃ ಹರಿರೇವ ಜಗತ್‌ ಪಿತೃಮಾತೃಗತಿಃ ॥ ೩.೧॥\n\nನಿನ್ನ ಪಾಲಿನ ಕರ್ಮ ಮಾಡು, ಬಂದುದನ್ನುಣ್ಣು. ಹರಿಯ ಚರಣದ ಅರಿವು ತಪ್ಪದಿರಲಿ. ನನ್ನದು ಎನ್ನುವ ಪ್ರತ್ಯೇಕ\nಸಂಕಲ್ಪ ಬೇಡ. ವೇದದಲ್ಲಿ ಹೇಳುವಂತೆ “ಭಗವಂತನ ಕಾಮನೆಯೇ ನನ್ನ ಕಾಮನೆಯಾಗಲಿ, ಆತನ ಇಚ್ಛೆಯೇ\nನನ್ನ ಇಚ್ಛೆಯಾಗಲಿ, ಅದರಿಂದ ನನ್ನ ಕಾಮನೆ ಭಗವಂತನ ಕಾಮನೆಗೆ ಶ್ರುತಿಗೂಡಲಿ'. ಹೀಗಾದಾಗ ಅಲ್ಲಿ\nಅಪಸ್ವರ ಹೊರಡುವುದಿಲ್ಲ. ನಮ್ಮ ಬಯಕೆ ಭಗವಂತನ ಇಚ್ಛೆಗೆ ಅನುರಣನವಾದಾಗ(State of Resonance)\nಬಾಳಿನ ಸಂಗೀತದಲ್ಲಿ ಮಾಧುರ್ಯ ನಿರ್ಮಾಣವಾಗುತ್ತದೆ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಸರ್ವಾನ್‌ ಅಶೇಷತಃ” ಎಂದು.\nಅಂದರೆ ನಿನ್ನೆಲ್ಲಾ ಸಂಕಲ್ಪವನ್ನು ಪೂರ್ಣವಾಗಿ ಬಿಡು ಎಂದು. ಭಗವಂತನ ಇಚ್ಚೆಗೆ ವಿರುದ್ಧವಾದ ಒಂದೂ\nಸಂಕಲ್ಪ ನಮ್ಮಲ್ಲಿರಬಾರದು. '“ನೀನು(ಭಗವಂತ) ಏನು ಬಯಸಿದೆಯೋ ಅದೇ ನನ್ನ ಸಂಕಲ್ಪ'-ಇದು ಒಬ್ಬ\nಯೋಗಿ ಧ್ಯಾನದಲ್ಲಿ ತೊಡಗಿಸಿಕೊಳ್ಳಬೇಕಾದ ಏಕೈಕ ಸಂಕಲ್ಪ.\n\nಸಂಕಲ್ಪ ಎಲ್ಲಿ ಹುಟ್ಟು ತ್ತದೋ ಅಲ್ಲೇ ಅದನ್ನು ತಡೆಯಬೇಕು. ಸಂಕಲ್ಪ ಹುಟ್ಟು ವುದೇ ಮನಸ್ಸಿ ನಿಂದ! ನಾವು ನಮ್ಮ\nಮನಸ್ಸಿಗೆ ನಿರಂತರ ಈ ರೀತಿ ಹೇಳಬೇಕು: “ನೀನು ಹುಚ್ಚು ಸಂಕಲ್ಪ ಮಾಡಬೇಡ, ಮಾಡಿದರೆ ಅದು ನಿನಗೆ\nಸಿಗುವುದಿಲ್ಲ, ನಂತರ ಸಿಗಲಿಲ್ಲ ಎಂದು ಚಡಪಡಿಸಬೇಕಾಗುತ್ತದೆ- ಆದ್ದರಿಂದ ಈ ಹುಚ್ಚು ಸಂಕಲ್ಪಗಳನ್ನು ಬಿಡು”\nಎಂದು. ಈ ರೀತಿ ಮನಸ್ಸಿಗೆ ನಿರಂತರ ಹೇಳಿ (repeatedly) ಅದನ್ನು ಪಳಗಿಸಬೇಕು. ಸಾಧಕನನ್ನು ದಾರಿ\nತಪ್ಪಿಸುವುದೂ ಮನಸ್ಸು, ದಾರಿ ಹೆಚ್ಚಿಸುವುದೂ ಮನಸ್ಸು. ಆದ್ದರಿಂದ ಮನಸ್ಸಿಗೆ ನಿರಂತರ ಈ ರೀತಿ ಹೇಳುತ್ತಾ\nಇದ್ದರೆ ಅದು ಕೊನೆಗೆ ಅದನ್ನು ಒಪ್ಪಿಕೊಳ್ಳುತ್ತದೆ.\n\nನಾವು ನಮ್ಮ ಹುಚ್ಚು ಸಂಕಲ್ಪವನ್ನು ಬಿಡಬೇಕಾದರೆ ಮೊದಲು ನಮ್ಮ ಇಂದ್ರಿಯ ಸಮುದಾಯವನ್ನು\nಹಿಡಿತದಲ್ಲಿಟ್ಟುಕೊಳ್ಳಬೇಕು. ನಾವು ನಮ್ಮಲ್ಲಿ ಒಳ್ಳೆಯ ಸಂಸ್ಕಾರವನ್ನು ರೂಢಿಸಿಕೊಳ್ಳಬೇಕು. ಇದಕ್ಕಾಗಿ ಹಿಂದೆ\nಚಿಕ್ಕ ಮಕ್ಕಳಿಗೆ ಅನೇಕ ಆಧ್ಯಾತ್ಮಿಕ ಸಂಸ್ಕಾರವನ್ನು ಹೇಳಿಕೊಡುತ್ತಿದ್ದರು. ಚಿಕ್ಕ ವಯಸ್ಸಿನಲ್ಲಿ ಮನಸ್ಸು ಹಸಿ\nಮಣ್ಣಿನಂತೆ. ಏನು ಹೇಳಿದರೂ ಅದರ ಯಥಾರ್ಥ ಗ್ರಹಣವಾಗುತ್ತದೆ. ಮನಸ್ಸಿನ ಗುಣವೆಂದರೆ ಅದನ್ನು ನಾವು\nಒಂದು ಕಡೆ ನಿರ್ಬಂಧ ಮಾಡಿದಾಗ ಅದು ಇನ್ನೊಂದು ಕಡೆ ಜಾರಿ ನುಣುಚಿಕೊಳ್ಳುತ್ತದೆ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ:\n“ಮನಸ್ಸನ್ನು ಜಾರಲು ಬಿಡಬೇಡ; ಎಲ್ಲಾ ಸಂಕಲ್ಪವನ್ನು ತ್ಯಾಗ ಮಾಡಿ ಭಗವಂತ ಒದಗಿಸಿಕೊಟ್ಟದ್ದನ್ನು ಭಗವದ್‌\nಪ್ರಸಾದವೆಂದು ಸ್ವೀಕರಿಸು; ಸಂತೋಷವಾಗಿ ಅದನ್ನು ಭೋಗಿಸು-ಅನುಭವಿಸು; ಇಲ್ಲದ್ದನ್ನು ಬೇಕು ಎಂದು\nಬಯಸಿ ಕೊರಗಬೇಡ” ಎಂದು.\n\nಈ ಹಿಂದೆ ಹೇಳಿದಂತೆ ಮನಸ್ಸನ್ನು ಒಮ್ಮೆಗೇ ತಿರುಗಿಸಲು ಬರುವುದಿಲ್ಲ. ಅದನ್ನು ಬಹಳ ನಿಧಾನವಾಗಿ\nತಿರುಗಿಸಬೇಕು. ಮೆಲ್ಲ-ಮೆಲ್ಲನೆ ಆ ಉತ್ಕೃಷ್ಟ ಆನಂದಕ್ಕೆ ಮನಸ್ಸನ್ನು ತಿರುಗಿಸಬೇಕು. ಇದಕ್ಕಾಗಿ “ನಿನ್ನ ವಿಶ್ಲೇಷಕ\nಬುದ್ಧಿಯನ್ನು ಬಳಸು” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಇದಕ್ಕೆ ಛಲ ಬೇಕು, ಧೈರ್ಯ ಬೇಕು. ಗುರಿ ಮುಟ್ಟುವ ತನಕ ನಾನು\nವಿಚಲಿತನಾಗಲಾರೆ ಎನ್ನುವ ಬುದ್ಧಿ(conviction), ಧೃತಿ(courage) ಬಹಳ ಮುಖ್ಯ. ಹೀಗೆ ತರ್ಕವನ್ನು ಮೀರಿ\nತರ್ಕಾತೀತ ಭಗವಂತನತ್ತ ಮನಸ್ಸನ್ನು ಅಣಿಗೊಳಿಸಬೇಕು. ಮನಸ್ಸು ಮೊದಲು ನಮ್ಮ ಸ್ವರೂಪವನ್ನು\n\nಗುರುತಿಸಿ ಅಲ್ಲಿ ನೆಲೆನಿಂತು ಆ ನಂತರ ಸ್ವರೂಪದಲ್ಲಿರುವ ಭಗವಂತನಲ್ಲಿ ನೆಲೆ ನಿಲ್ಲಬೇಕು. ಒಮ್ಮೆ ನೆಲೆ ನಿಂತ\nಮನಸ್ಸನ್ನು ಬೇರೆ ಯಾವುದೇ ಚಿಂತೆಗೆ ಒಡ್ಡದೆ ಅದನ್ನು ಅಲ್ಲೇ ನೆಲೆಗೊಳಿಸಬೇಕು.\n",
  "6.26": "ಯತಃ ಯತಃ ನಿಶ್ಚರತಿ ಮನಃ ಚಂಚಲಮ್‌ ಅಸ್ಥಿರಮ್‌ |\n\nತತಃ ತತಃ ನಿಯಮ್ಯ ಏತತ್‌ ಆತ್ಮನಿ ಏವ ವಶಮ್‌ ನಯೇತ್‌ -ಗಟ್ಟಿಗೊಳ್ಳದೆ ಎತ್ತೆತ್ತ ಸರಿಯುವ ಬಗೆ,\nಯಾವೆಡೆಯೆಲ್ಲ ಹರಿಯಿತು, ಆಯಾ ಕಡೆಯಿಂದ ಮತ್ತೆ ಹೊರಳಿಸಿ ಭಗವಂತನಲ್ಲೇ ನಿಲ್ಲುವಂತೆ ಹಿಡಿತಕ್ಕೆ\nತರಬೇಕು.\n\nನಮ್ಮ ಮನಸ್ಸು ಬಹಳ ಚಂಚಲ. ಈ ಕಾರಣದಿಂದ ಅದು ಐಲ್ದೆಡೆ ಹರಿಯುತ್ತಿರುತ್ತದೆ. ಅದು ಎಲ್ಲಿಎಲ್ಲಿ\nಜಾರುತ್ತದೋ ಅಲ್ಲಿಅಲ್ಲಿ ಭಗವಂತನೆಂಬ ಒಡ್ಡು ಹಾಕಿ ಅದನ್ನು ಭಗವಂತನಲ್ಲಿ ನೆಲೆನಿಲ್ಲುವಂತೆ ಮಾಡಬೇಕು.\nಇದಕ್ಕೆ ನಿರಂತರ ಪ್ರಯತ್ನ ಅಗತ್ಯ.",
  "6.27": "ಪ್ರಶಾಂತ ಮನಸಮ್‌ ಹಿ ಎನಮ್‌ ಯೋಗಿನಮ್‌ ಸುಖಮ್‌ ಉತ್ತಮಮ್‌ |।\n\nಉಪೈತಿ ಶಾಂತರಜಸಮ್‌ ಬ್ರಹ್ಮಭೂತಮ್‌ ಅಕಲ್ಮಷಮ್‌ -ವಿಷಯಗಳತ್ತ ಹರಿಯದೆ ಹಾಯಾದ\nಬಗೆಯವನನ್ನು, ರಜೋಗುಣದ ಬಿಸಿಯಳಿದು ತಿಳಿಯಾದವನನ್ನು, ಭಗವಂತನಲ್ಲೇ ನೆಲೆನಿಂತ ಇಂತಹ\nಯೋಗಿಯನ್ನು ಸುಖದ ಸುಗ್ಗಿ ನುಗ್ಗಿ ಬರುತ್ತದೆ.\n\nಒಮ್ಮೆ ನಮ್ಮ ಮನಸ್ಸು ಭಗವಂತನಲ್ಲಿ ನೆಲೆ ನಿಂತಿತೆಂದರೆ ಗೊಂದಲದ ಗೂಡಾದ ಮನಸ್ಸು\nಪ್ರಶಾಂತವಾಗುತ್ತದೆ. ಇದನ್ನು ಸಾಧಿಸಿದ ವ್ಯಕ್ತಿ ಎಂತಹ ಸನ್ನಿ ವೇಶದಲ್ಲೂ ಉದ್ವೇಗಕ್ಕೊಳಗಾಗುವುದಿಲ್ಲ.\nಜೀವನದಲ್ಲಿ ನಾವು ಅನುಭವಿಸಬೇಕಾದ ನಿಜವಾದ ಶ್ರೇಷ್ಠ ಸುಖ ಏನು ಎನ್ನುವುದು ಈ ಸ್ಥಿತಿಯಲ್ಲಿ ತಿಳಿಯುತ್ತದೆ.\nಮನಸ್ಸು ಸಾಮಾನ್ಯವಾಗಿ ಬಯಸುವ ರಾಜಸ ಸುಖದಲ್ಲಿ ಇರುವ ನಿರಾಶೆ ಇಲ್ಲಿ ಎಂದೂ ಇರದು. ಈ ಸ್ಥಿತಿಯಲ್ಲಿ\nನಾವು ಸ್ವಚ್ಛವಾಗುತ್ತೇವೆ. ಇದು ನಿಜವಾದ ಮಡಿ. ಮನಸ್ಸಿನ ಸ್ವಚ್ಛತೆಯನ್ನು ಸಾಧಿಸದೇ ಬಾಹ್ಯ ಮಡಿ\nಮಾಡುವುದರಿಂದ ಯಾವ ಉಪಯೋಗವೂ ಇಲ್ಲ. ಶುದ್ಧವಾದ ಮನಸ್ಸಿಗೆ ಯಾವುದೂ ಮೈಲಿಗೆ ಅಲ್ಲ! ಮನಸ್ಸು\nಮಡಿಯಾದರೆ ಅವನು ಮೈಲಿಗೆಯಾಗುವ ಸಾಧ್ಯತೆಯೇ ಇಲ್ಲ. ಇದು ಮಾನವ ತನ್ನ ಜೀವಮಾನದಲ್ಲಿ\nಪಡೆಯಬಹುದಾದ ಪರಮಾನಂದದ ಸ್ಥಿತಿ.\n",
  "6.28": "ಯುಂಜನ್‌ ಏವಮ್‌ ಸದಾ ಆತ್ಮಾನಮ್‌ ಯೋಗೀ ವಿಗತ ಕಲ್ಮಷಃ |\nಸುಖೇನ ಬ್ರಹ್ಮಸಂಸ್ಟರ್ಶಮ್‌ ಅತ್ಯಂತಮ್‌ ಸುಖಮ್‌ ಅಶ್ನು ತೇ -- ಹೀಗೆ ಕೊಳೆಯಳಿದು ಸದಾ ಭಗವಂತನನ್ನು\nಧ್ಯಾನಿಸುವ ಸಾಧಕನು ಹಾಯಾಗಿ ಭಗವದನುಭವದ ಪರಮ ಸುಖವನ್ನು ಉಣ್ಣುತ್ತಾನೆ.\n\nಭಗವದ್‌ ಅನುಭೂತಿ ಆದಾಗ ಆಗುವ ಅಂತರಂಗದ ಆನಂದವನ್ನು ಇನ್ನೊಂದು ರೀತಿಯಲ್ಲಿ ಕೃಷ್ಣ ಇಲ್ಲಿ\nವಿವರಿಸಿದ್ದಾನೆ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ಯುಂಜನ್‌ ಏವಂ ಸದಾತ್ಮಾನಂ ಯೋಗೀ ವಿಗತಕಲ್ಮಷಃ” ಎಂದು. ಕೃಷ್ಣನ\nಈ ನುಡಿಯನ್ನು ಎರಡು ರೂಪದಲ್ಲಿ ಕಾಣಬಹುದು. ಮೊದಲನೆಯದಾಗಿ “ವಿಗತಕಲ್ಮಷ ಸನ್‌ ಆತ್ಮಾನಂ\nಯುಂಜನ್‌ ಹಾಗೂ ಎರಡನೇಯದಾಗಿ “ಆತ್ಮಾನಂ ಯುಂಜನ್‌ ಸನ್‌ ವಿಗತಕಲ್ಮಷಃ”. ನಾವು ಮೊದಲು\nವಿಗತಕಲ್ಮಶವಾದ ಮನಸ್ಸಿನಿಂದ ಭಗವಂತನನ್ನು ಕಾಣಬೇಕು. ನಂತರ ಭಗವಂತನನ್ನು ಧ್ಯಾನ ಮಾಡುತ್ತಾ\nವಿಗತಕಲ್ಮಷರಾಗಬೇಕು. ಭಗವಂತನ ಧ್ಯಾನಕ್ಕೋಸ್ಕರ ಮನಸ್ಸನ್ನು ಸ್ವಚ್ಛಗೊಳಿಸಿ ಒಮ್ಮೆ ಭಗವಂತನನ್ನು\nಕಾಣಬಹುದು. ಆದರೆ ಭಗವಂತನ ಅನುಭವದಿಂದ ಕೆಳಗಿಳಿದ ತಕ್ಷಣ ತಾಮಸ ಆವೇಶ ನಮ್ಮ ಮನಸ್ಸನ್ನು\nಕೆಡಿಸಬಹುದು. ಅದಕ್ಕಾಗಿ ಸದಾ ಭಗವದ್‌ ಅನುಭೂತಿಯಲ್ಲೇ ನೆಲೆಗೊಳ್ಳಬೇಕು. ಇದರರ್ಥ ದಿನದ ಇಪತ್ನಾಲ್ಕು\nಗಂಟೆ ಧ್ಯಾನದಲ್ಲೇ ಇರಬೇಕು ಎಂದಲ್ಲ. ಬದಲಾಗಿ ಸದಾ ಭಗವಂತನ ಗುಂಗಿನಲ್ಲಿರುವುದು. ಹೀಗಿದ್ದಾಗ\nಮನಸ್ಸು ನಿರಂತರ ಸ್ವಚ್ಛವಾಗಿರುತ್ತದೆ. ಹೀಗೆ ಭಗವದೃಜ್ಞೆ ಗಟ್ಟಿಗೊಂಡಾಗ ಸಾಧಕ ಅನಾಯಾಸವಾಗಿ\nಭಗವಂತನನ್ನು ನೇರವಾಗಿ ಕಾಣುವ ಅತ್ಯಂತ ಸುಖಾನುಭವವನ್ನು ಪಡೆಯತ್ತಾನೆ.\n\nಧ್ಯಾನ ಪ್ರಕ್ರಿಯೆಯನ್ನು ವಿವರಿಸಿದ ಕೃಷ್ಣ ಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ಭಗವಂತನಲ್ಲಿ ಎಂತಹ ಗುಣದ ಅನುಸಂಧಾನ\nಮಾಡಬೇಕು ಎನ್ನುವುದನ್ನು ವಿವರಿಸುತ್ತಾನೆ. ದೇವರು ಎಂದರೆ ಎಲ್ಲೋ ಸತ್ಯಲೋಕದಿಂದಾಚೆಗಿನ\nವೈಕುಂಠದಲ್ಲಿನ ಅಂತಃಪುರದ ಕೋಣೆಯಲ್ಲಿ ಕುಳಿತ ಒಬ್ಬ ವ್ಯಕ್ತಿ ಎಂದು ಅನುಸಂಧಾನ ಮಾಡುವುದಲ್ಲ. ದೇವರ\nಬಗ್ಗೆ ನಮ್ಮ ಅನುಸಂಧಾನ ಹೇಗಿರಬೇಕು ಎನ್ನುವುದನ್ನು ಇಲ್ಲಿ ಕೃಷ್ಣ ವಿವರಿಸುತ್ತಾನೆ.",
  "6.29": "ಸರ್ವ ಭೂತ ಸ್ಥ್ಫಮ್‌ ಆತ್ಮಾನಮ್‌ ಸರ್ವ ಭೂತಾನಿ ಚ ಆತ್ಮನಿ ।\n\nಈಕ್ಷತೇ ಯೋಗ ಯುಕ್ತ ಆತ್ಮಾ ಸರ್ವತ್ರ ಸಮದರ್ಶನಃ -ಧ್ಯಾನಯೋಗಕ್ಕೆ ಬಗೆ ಸಜ್ಜುಗೊಂಡ ಸಾಧಕ ಎಲ್ಲಾ\nಜೀವಿಗಳಲ್ಲೂ ಭಗವಂತನನ್ನು ಕಾಣುತ್ತಾನೆ ಮತ್ತು ಎಲ್ಲಾ ಜೀವಿಗಳನ್ನು ಭಗವಂತನಲ್ಲಿ ಕಾಣುತ್ತಾನೆ. ಎಲ್ಲೆಡೆ\nಇರುವ ಭಗವಂತ ಏಕರೂಪನೆಂದು ಕಾಣುತ್ತಾನೆ.\n\nನಾವು ಭಗವಂತನನ್ನು ಬ್ರಹ್ಮ ಎನ್ನುತ್ತೇವೆ, ಪರಮಾತ್ಮ ಎನ್ನುತ್ತೇವೆ. ಏನು ಹಾಗೆಂದರೆ? ಎಲ್ಲಾ ಕಾಲದಲ್ಲೂ\nಎಲ್ಲಾ ದೇಶದಲ್ಲೂ ತುಂಬಿರುವ ಬೃಹತ್ತಾದದ್ದು ಬ್ರಹ್ಮ. ಎಲ್ಲಾ ಕಡೆ ವ್ಯಾಪಿಸಿರುವ ಸರ್ವ ಗುಣಪೂರ್ಣನಾಗಿ\nಕಾಲತಃ, ದೇಶತಃ, ಗುಣತಃ, ಶಕ್ತಿತಃ ಅನಂತವಾಗಿರುವವ ಪರಮಾತ್ಮ. ಇಲ್ಲಿ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ:\n“ಸರ್ವಭೂತಸ್ಥಮಾತ್ಮಾನಂ” ಎಂದು. ಅಂದರೆ ಸಮಸ್ತ ಜೀವಜಾತದೊಳಗೆ ಅಂತರ್ಯಾಮಿಯಾಗಿ ಬಿಂಬರೂಪಿ\nಭಗವಂತನಿದ್ದಾನೆ. ಅಷ್ಟೇ ಅಲ್ಲ “ಸರ್ವ ಭೂತಾನಿ ಚ ಆತ್ಮನಿ” ಅಂದರೆ ಸಮಸ್ತ ಜೀವಗಳೂ ಭಗವಂತನಲ್ಲಿವೆ.\nಇದರ ಪೂರ್ಣ ಅರ್ಥ: ಭಗವಂತ ನಮ್ಮ ಒಳಗೂ ಹೊರಗೂ ತುಂಬಿದ್ದಾನೆ' ಎಂದು. ಇದು ನಾವು ಉಪಾಸನೆ\nಮಾಡುವಾಗ ತಿಳಿದುಕೊಳ್ಳಬೇಕಾದ ಮುಖ್ಯವಾದ ಅಂಶ. ಒಬ್ಬ ಧ್ಯಾನಯೋಗದಲ್ಲಿರುವ ಸಾಧಕ ಭಗವಂತನ\nಸರ್ವಗತತ್ವವನ್ನು ಕಾಣುವ ಬಗೆಯಿದು.\n\nಭಗವಂತ ಎಲ್ಲಾ ಜೀವದಲ್ಲೂ ತುಂಬಿದ್ದರೂ ಕೂಡಾ ಒಬ್ಬ ಸಾಧಕ ಆತನನ್ನು “ಸರ್ವತ್ರ ಸಮದರ್ಶನಃ”- ಅಂದರೆ\nಏಕರೂಪದಲ್ಲಿ ಕಾಣುತ್ತಾನೆ. ಭಗವಂತನ ಅವತಾರ, ಆತನ ಆವೇಶ, ಸನ್ನಿ ಧಾನ, ಗುಣ, ಕೃತಿ, ರೂಪ ಎಲ್ಲವೂ\nಅಖಂಡ. ಅದರಲ್ಲಿ ವ್ಯತ್ಯಾಸವಿಲ್ಲ. ಎಲ್ಲವುದರ ಒಳಗೂ ಹೊರಗೂ ತುಂಬಿರುವ ಆತ ಏಕರೂಪನಾಗಿದ್ದಾನೆ.\nಭಗವಂತ ಸರ್ವಾಂತರ್ಯಾಮಿ ಮತ್ತು ಸರ್ವಗತ ಎನ್ನುವ\nಅನುಸಂಧಾನ ನಮ್ಮ ನಿತ್ಯ ಉಪಾಸನೆಯಲ್ಲಿರಬೇಕು.\n\nಯೋ ಮಾಂ ಪಶ್ಯತಿ ಸರ್ವತ್ರ ಸರ್ವಂ ಚ ಮಯಿ ಪಶ್ಯತಿ ।\n\nತಸ್ಯಾಹಂ ನ ಪ್ರಣಶ್ಯಾಮಿ ಸ ಚ ಮೇ ನ ಪ್ರಣಶ್ಯತಿ 1೩೦॥\n\nಯಃ ಮಾಮ್‌ ಪಶ್ಯತಿ ಸರ್ವತ್ರ ಸರ್ವಮ್‌ ಚ ಮಯಿ ಪಶ್ಯತಿ |\nತಸ್ಯ ಅಹಮ್‌ ನ ಪ್ರಣಶ್ಯಾಮಿ ಸಃ ಚಮೇನ ಪ್ರಣಶ್ಯತಿ -ಯಾರು ನನ್ನ ನ್ನು ಎಲ್ಲೆಡೆ ಕಾಣುತ್ತಾರೆ ಮತ್ತು\nಎಲ್ಲವನ್ನೂ ನನ್ನಲ್ಲಿ ಕಾಣುತ್ತಾರೆ ಅವರಿಗೆ ನಾನು ಎರವಾಗಲಾರೆ; ಅವರೂ ನನಗೆ ಎರವಾಗಲಾರರು.\n\nಮುಂದುವರಿದು ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಯಾರು ಹೀಗೆ ನನ್ನನ್ನು ಎಲ್ಲರಲ್ಲಿಯೂ ಮತ್ತು ಎಲ್ಲರನ್ನು ನನ್ನಲ್ಲಿ\nಕಾಣುತ್ತಾನೋ ಅವನಿಗೆ ನಾನೆಂದೂ ಇಲ್ಲವಾಗುವುದಿಲ್ಲ. ಸದಾ ಆತನ ಯೋಗ ಕ್ಷೇಮದ ಹೊಣೆ ನನ್ನದು. ಅದೇ\nರೀತಿ “ನಾನು ಆತನ ಯೋಗಕ್ಷೇಮವನ್ನು ನೋಡಿಕೊಳ್ಳುತ್ತೇನೆ' ಎನ್ನುವ ಎಚ್ಚರ ಸದಾ ಆತನಲ್ಲಿರುತ್ತದೆ” ಎಂದು.\n\nಹೀಗೆ ಭಗವಂತನ ಅನ್ಯೋನ್ಯ ಸಂಬಂಧ, 'ದೇವರು ಎಂದೂ ನಮ್ಮನ್ನು ಬಿಟ್ಟು ಹಾಕುವುದಿಲ್ಲ' ಎನ್ನುವ ಎಚ್ಚರ\nನಮ್ಮಲ್ಲಿ ಸದಾ ಜಾಗೃತವಾಗಿರುತ್ತದೆ. ಹಿಂದೆ ಹೇಳಿದಂತೆ ಭಗವಂತ ನಾವು ಆತನನ್ನು ಹೇಗೆ ನೋಡುತ್ತೆವೋ\nಹಾಗೆ. ಈ ಕಾರಣದಿಂದ ನಮ್ಮಲ್ಲಿನ ಈ ಎಚ್ಚರದಿಂದ ಯಾವತ್ತೂ ಜೀವನದಲ್ಲಿ ಬಗೆಹರಿಯದಂತಹ ಸಮಸ್ಯೆ\nನಮಗೆ ಬರುವುದಿಲ್ಲ. ಪ್ರರಾಬ್ಧಕರ್ಮದಿಂದ ಬಂದರೂ ಕೂಡಾ ಕಾಣದ ಕೈ ನಮ್ಮನ್ನು ಕೈ ಹಿಡಿದು ನಡೆಸುತ್ತಿರುವ\nಅನುಭವವಾಗುತ್ತದೆ. “ನನ್ನನ್ನು ಕಾಪಾಡುವವನಿದ್ದಾನೆ ಅವನು ನನ್ನ ಯೋಗ-ಕ್ಷೇಮವನ್ನು ನೋಡಿಕೊಳ್ಳುತ್ತಾನೆ,\nನಾನೇಕೆ ಹೆದರಬೇಕು' ಎನ್ನುವ ದೈರ್ಯ ಬರುತ್ತದೆ. ಕೆಟ್ಟ ಯೋಚನೆ ದೂರವಾಗುತ್ತದೆ. ಸಾಮಾಜಿಕ\nಪ್ರತಿಕ್ರೀಯೆಗಳಿಗೆ, ಟೀಕೆ-ಟಿಪ್ಪಣಿಗಳಿಗೆ, ಅಪವಾದಗಳಿಗೆ, ನಿಂದನೆಗಳಿಗೆ, ಯಾವುದಕ್ಕೂ ವಿಚಲಿತನಾಗುವುದಿಲ್ಲ.\nಭಗವಂತ ಕೈಬಿಟ್ಟ ಎನ್ನುವ ಸ್ಥಿತಿ ಭಕ್ತನಿಗೆ ಎಂದೂ ಬರುವುದಿಲ್ಲ. ಭಗವಂತ ಎಂದೂ ತನ್ನ ಆತ್ಮೀಯ ಭಕ್ತನಿಂದ\nದೂರವಾಗುವುದಿಲ್ಲ. ಇದಕ್ಕಾಗಿ ಭಗವಂತನನ್ನು 'ಭಕ್ತಪರಾಧೀನ' ಎನ್ನುವುದು. ಈ ಕುರಿತು ಇನ್ನಷ್ಟು ವಿವರವಾಗಿ\nಕೃಷ್ಣ ಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ವಿವರಿಸಿದ್ದಾನೆ.\n",
  "6.30": "ಸರ್ವಭೂತಸ್ಥಿತಂ ಯಃ ಮಾಮ್ ಭಜತಿ ಏಕತ್ವಮ್ ಆಸ್ಥಿತಃ |\nಸರ್ವಥಾ ವರ್ತಮಾನಃ ಅಪಿ ಸಃ ಯೋಗೀ ಮಯಿ ವರ್ತತೇ -- ಎಲ್ಲಾ ಜೀವಿಗಳಲ್ಲಿರುವ ನನ್ನನ್ನು ಏಕರೀತಿಯಿಂದ ತಿಳಿದು ಪೂಜಿಸುವವನು ಯಾವ ಸ್ಥಿತಿಯಲ",
  "6.31": "ಸರ್ವಭೂತಸ್ಥಿತಂ ಯಃ ಮಾಮ್‌ ಭಜತಿ ಏಕತ್ವಮ್‌ ಆಸ್ಥಿತಃ |\nಸರ್ವಥಾ ವರ್ತಮಾನಃ ಅಪಿ ಸಃ ಯೋಗೀ ಮಯಿ ವರ್ತತೇ-ಎಲ್ಲಾ ಜೀವಿಗಳಲ್ಲಿರುವ ನನ್ನನ್ನು ಏಕರೀತಿಯಿಂದ\nತಿಳಿದು ಪೂಜಿಸುವವನು ಯಾವ ಸ್ಥಿತಿಯಲ್ಲಿದ್ದರೂ ನನ್ನಲ್ಲಿರುತ್ತಾನೆ.\n\nಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಸರ್ವಗತನಾದ ಭಗವಂತ ಎಲ್ಲಾ ಕಡೆ ಏಕರೂಪವಾಗಿದ್ದಾನೆ ಎನ್ನುವ ಅನುಸಂಧಾನ ಮತ್ತು\nನಿರಂತರ ಭಕ್ತಿ ಇರುವ ಸಾಧಕ, ಆತ ಹೇಗೇ ಇರಲಿ, ಅವನು ನನ್ನನ್ನು ಸೇರುವುದು ನಿಶ್ಚಿತ” ಎಂದು. ಅಪರೋಕ್ಷ\nಜ್ಞಾನ ಪಡೆದವ ಭಗವಂತನಿಂದ ಎಂದೂ ದೂರ ಸರಿಯುವುದಿಲ್ಲ. ಆತ ಮೋಕ್ಷವನ್ನು ಪಡೆದು ಭಗವಂತನಲ್ಲಿ\nನೆಲೆಸುತ್ತಾನೆ.\n\nಆತ್ಮೌಪಮ್ಯೇನ ಸರ್ವತ್ರ ಸಮಂ ಪಶ್ಯತಿ ಯೋ$ರ್ಜುನ |\n\nಸುಖಂವಾ ಯದಿವಾ ದುಃಖಂಸಯೋಗೀ ಪರಮೋ ಮತಃ ॥ಷ೩೨॥\n\nಆತ್ಮಔಪಮ್ಯೇನ ಸರ್ವತ್ರ ಸಮಮ್‌ ಪಶ್ಯತಿ ಯಃ ಅರ್ಜುನ ।\n\nಸುಖಮ್‌ ವಾ ಯದಿ ವಾ ದುಃಖಮ್‌ ಸಃ ಯೋಗೀ ಪರಮಃ ಮತಃ -ಸುಖವಿರಲಿ, ದುಃಖವಿರಲಿ, ಎಲ್ಲರ ಬೇಕು-\nಬೇಡಗಳನ್ನು ತನ್ನ ಹಾಗೆಯೇ ಸಮಾನತೆಯಿಂದ ಕಾಣುವವನು, ಓ ಅರ್ಜುನಾ, ಬಹಳ ದೊಡ್ಡ ಸಾಧಕ\nಎನ್ನುವುದು ತೀರ್ಮಾನ.\n\nಕೃಷ್ಣ ನಮಗೆ ಸಮದೃಷ್ಟಿ ಬಗ್ಗೆ ಹಿಂದೆ ಕೂಡಾ ಹೇಳಿದ್ದ. ಇಲ್ಲಿ ಮುಖ್ಯವಾಗಿ ಸಾತ್ವಿಕರೊಂದಿಗೆ,\nಭಗವದ್ಭಕ್ತರೊಂದಿಗೆ ಒಬ್ಬ ಸಾಧಕ ಯಾವ ರೀತಿ ಸಮದರ್ಶನ ಬೆಳೆಸಿಕೊಳ್ಳುತ್ತಾನೆ ಎನ್ನುವುದನ್ನು\nವಿವರಿಸಿದ್ದಾನೆ. ಯೋಗಿಗಳಲ್ಲಿ ಶ್ರೇಷ್ಠನಾದವನು ತನ್ನಂತೆಯೇ ಇನ್ನೊಬ್ಬರು ಎಂದು ತಿಳಿದಿರುತ್ತಾನೆ. ನಮಗೆ\nಯಾವುದು ದುಃಖವಾಗುತ್ತದೋ ಅದು ಇನ್ನೊಬ್ಬರಿಗೂ ದುಃಖವನ್ನು ಕೊಡುತ್ತದೆ ಎನ್ನುವ ಸತ್ಯವನ್ನು ಆತ\nಅರಿತಿರುತ್ತಾನೆ. ಎಲ್ಲರಿಗೂ ಸುಖ-ದುಃಖಗಳಿವೆ, ನನ್ನಂತೆಯೇ ಅವರು ದುಃಖವನ್ನು ಇಷ್ಟಪಡುವುದಿಲ್ಲ ಎನ್ನುವ\nಎಚ್ಚರದಿಂದ ಸಾಧಕ ವ್ಯವಹರಿಸುತ್ತಾನೆ. ಯಾರು ಇನ್ನೊಬ್ಬರ ನೋವನ್ನು ತನ್ನ ನೋವಿನಷ್ಟೇ ನೋವಿನಿಂದ\nಕಾಣುತ್ತಾನೋ, ಯಾರು ಇನ್ನೊಬ್ಬರ ಸಂತೋಷವನ್ನು- ಯಶಸ್ಸನ್ನು ತನ್ನ ಯಶಸ್ಸೆಂದು ತಿಳಿದು ಖುಷಿ\nಪಡುತ್ತಾನೋ- ಅವನು ಬಹಳ ದೊಡ್ಡ ಯೋಗ ಸಾಧಕ.\n\nಭಗವದ್ಭಕ್ತರಲ್ಲಿ ಭಗವಂತನ ವಿಶೇಷ ಸನ್ನಿಧಾನವಿದೆ. ಆದ್ದರಿಂದ ಅವರ ಸುಖ-ದುಃಖಕ್ಕೆ ನಾವು ಸ್ಪಂದಿಸಿದಾಗ\nಅದು ಅವರೊಳಗಿನ ಭಗವಂತನ ಪೂಜೆಯಾಗುತ್ತದೆ.\n\nಈ ಅಧ್ಯಾಯದಲ್ಲಿ ಇಲ್ಲಿಯವರೆಗೆ ಧ್ಯಾನದ ಬಗ್ಗೆ ಕೃಷ್ಣ ವಿಸ್ತಾರವಾಗಿ ಹೇಳಿದ. ಕೃಷ್ಣನ ಈ ವಿವರಣೆಯಲ್ಲಿ\nಎಲ್ಲರಿಗೂ ಕಾಣುವ ಒಂದೇ ಒಂದು ಸರ್ವೇ ಸಾಮಾನ್ಯ ಕಷ್ಟದ ವಿಷಯವೆಂದರೆ \"ಚಂಚಲ ಮನಸ್ಸನ್ನು ಹೊಂದಿದ\nನಾವು ಅದನ್ನು ನಿಯಂತ್ರಿಸಿ ಸಮದೃಷ್ಟಿ ಬೆಳೆಸಿಕೊಳ್ಳುವುದು', ಇದು ನಿಜವಾಗಿಯೂ ಸಾಧ್ಯವೇ? ಮುಂದಿನ\nಶ್ಲೋಕದಲ್ಲಿ ಅರ್ಜುನ ನಮ್ಮೆಲ್ಲರ ಪರ ಈ ಪ್ರಶ್ನೆಯನ್ನು ಕೃಷ್ಣನಲ್ಲಿ ಮಂಡಿಸುತ್ತಾನೆ.",
  "6.32": "ಸರ್ವಭೂತಸ್ಥಿತಂ ಯಃ ಮಾಮ್‌ ಭಜತಿ ಏಕತ್ವಮ್‌ ಆಸ್ಥಿತಃ |\nಸರ್ವಥಾ ವರ್ತಮಾನಃ ಅಪಿ ಸಃ ಯೋಗೀ ಮಯಿ ವರ್ತತೇ-ಎಲ್ಲಾ ಜೀವಿಗಳಲ್ಲಿರುವ ನನ್ನನ್ನು ಏಕರೀತಿಯಿಂದ\nತಿಳಿದು ಪೂಜಿಸುವವನು ಯಾವ ಸ್ಥಿತಿಯಲ್ಲಿದ್ದರೂ ನನ್ನಲ್ಲಿರುತ್ತಾನೆ.\n\nಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಸರ್ವಗತನಾದ ಭಗವಂತ ಎಲ್ಲಾ ಕಡೆ ಏಕರೂಪವಾಗಿದ್ದಾನೆ ಎನ್ನುವ ಅನುಸಂಧಾನ ಮತ್ತು\nನಿರಂತರ ಭಕ್ತಿ ಇರುವ ಸಾಧಕ, ಆತ ಹೇಗೇ ಇರಲಿ, ಅವನು ನನ್ನನ್ನು ಸೇರುವುದು ನಿಶ್ಚಿತ” ಎಂದು. ಅಪರೋಕ್ಷ\nಜ್ಞಾನ ಪಡೆದವ ಭಗವಂತನಿಂದ ಎಂದೂ ದೂರ ಸರಿಯುವುದಿಲ್ಲ. ಆತ ಮೋಕ್ಷವನ್ನು ಪಡೆದು ಭಗವಂತನಲ್ಲಿ\nನೆಲೆಸುತ್ತಾನೆ.\n\nಆತ್ಮೌಪಮ್ಯೇನ ಸರ್ವತ್ರ ಸಮಂ ಪಶ್ಯತಿ ಯೋ$ರ್ಜುನ |\n\nಸುಖಂವಾ ಯದಿವಾ ದುಃಖಂಸಯೋಗೀ ಪರಮೋ ಮತಃ ॥ಷ೩೨॥\n\nಆತ್ಮಔಪಮ್ಯೇನ ಸರ್ವತ್ರ ಸಮಮ್‌ ಪಶ್ಯತಿ ಯಃ ಅರ್ಜುನ ।\n\nಸುಖಮ್‌ ವಾ ಯದಿ ವಾ ದುಃಖಮ್‌ ಸಃ ಯೋಗೀ ಪರಮಃ ಮತಃ -ಸುಖವಿರಲಿ, ದುಃಖವಿರಲಿ, ಎಲ್ಲರ ಬೇಕು-\nಬೇಡಗಳನ್ನು ತನ್ನ ಹಾಗೆಯೇ ಸಮಾನತೆಯಿಂದ ಕಾಣುವವನು, ಓ ಅರ್ಜುನಾ, ಬಹಳ ದೊಡ್ಡ ಸಾಧಕ\nಎನ್ನುವುದು ತೀರ್ಮಾನ.\n\nಕೃಷ್ಣ ನಮಗೆ ಸಮದೃಷ್ಟಿ ಬಗ್ಗೆ ಹಿಂದೆ ಕೂಡಾ ಹೇಳಿದ್ದ. ಇಲ್ಲಿ ಮುಖ್ಯವಾಗಿ ಸಾತ್ವಿಕರೊಂದಿಗೆ,\nಭಗವದ್ಭಕ್ತರೊಂದಿಗೆ ಒಬ್ಬ ಸಾಧಕ ಯಾವ ರೀತಿ ಸಮದರ್ಶನ ಬೆಳೆಸಿಕೊಳ್ಳುತ್ತಾನೆ ಎನ್ನುವುದನ್ನು\nವಿವರಿಸಿದ್ದಾನೆ. ಯೋಗಿಗಳಲ್ಲಿ ಶ್ರೇಷ್ಠನಾದವನು ತನ್ನಂತೆಯೇ ಇನ್ನೊಬ್ಬರು ಎಂದು ತಿಳಿದಿರುತ್ತಾನೆ. ನಮಗೆ\nಯಾವುದು ದುಃಖವಾಗುತ್ತದೋ ಅದು ಇನ್ನೊಬ್ಬರಿಗೂ ದುಃಖವನ್ನು ಕೊಡುತ್ತದೆ ಎನ್ನುವ ಸತ್ಯವನ್ನು ಆತ\nಅರಿತಿರುತ್ತಾನೆ. ಎಲ್ಲರಿಗೂ ಸುಖ-ದುಃಖಗಳಿವೆ, ನನ್ನಂತೆಯೇ ಅವರು ದುಃಖವನ್ನು ಇಷ್ಟಪಡುವುದಿಲ್ಲ ಎನ್ನುವ\nಎಚ್ಚರದಿಂದ ಸಾಧಕ ವ್ಯವಹರಿಸುತ್ತಾನೆ. ಯಾರು ಇನ್ನೊಬ್ಬರ ನೋವನ್ನು ತನ್ನ ನೋವಿನಷ್ಟೇ ನೋವಿನಿಂದ\nಕಾಣುತ್ತಾನೋ, ಯಾರು ಇನ್ನೊಬ್ಬರ ಸಂತೋಷವನ್ನು- ಯಶಸ್ಸನ್ನು ತನ್ನ ಯಶಸ್ಸೆಂದು ತಿಳಿದು ಖುಷಿ\nಪಡುತ್ತಾನೋ- ಅವನು ಬಹಳ ದೊಡ್ಡ ಯೋಗ ಸಾಧಕ.\n\nಭಗವದ್ಭಕ್ತರಲ್ಲಿ ಭಗವಂತನ ವಿಶೇಷ ಸನ್ನಿಧಾನವಿದೆ. ಆದ್ದರಿಂದ ಅವರ ಸುಖ-ದುಃಖಕ್ಕೆ ನಾವು ಸ್ಪಂದಿಸಿದಾಗ\nಅದು ಅವರೊಳಗಿನ ಭಗವಂತನ ಪೂಜೆಯಾಗುತ್ತದೆ.\n\nಈ ಅಧ್ಯಾಯದಲ್ಲಿ ಇಲ್ಲಿಯವರೆಗೆ ಧ್ಯಾನದ ಬಗ್ಗೆ ಕೃಷ್ಣ ವಿಸ್ತಾರವಾಗಿ ಹೇಳಿದ. ಕೃಷ್ಣನ ಈ ವಿವರಣೆಯಲ್ಲಿ\nಎಲ್ಲರಿಗೂ ಕಾಣುವ ಒಂದೇ ಒಂದು ಸರ್ವೇ ಸಾಮಾನ್ಯ ಕಷ್ಟದ ವಿಷಯವೆಂದರೆ \"ಚಂಚಲ ಮನಸ್ಸನ್ನು ಹೊಂದಿದ\nನಾವು ಅದನ್ನು ನಿಯಂತ್ರಿಸಿ ಸಮದೃಷ್ಟಿ ಬೆಳೆಸಿಕೊಳ್ಳುವುದು', ಇದು ನಿಜವಾಗಿಯೂ ಸಾಧ್ಯವೇ? ಮುಂದಿನ\nಶ್ಲೋಕದಲ್ಲಿ ಅರ್ಜುನ ನಮ್ಮೆಲ್ಲರ ಪರ ಈ ಪ್ರಶ್ನೆಯನ್ನು ಕೃಷ್ಣನಲ್ಲಿ ಮಂಡಿಸುತ್ತಾನೆ.",
  "6.33": "ಅರ್ಜುನಃ ಉವಾಚ-ಅರ್ಜುನ ಕೇಳಿದನು:\n\nಯಃ ಅಯಮ್‌ ಯೋಗಃ ತ್ವಯಾ ಪ್ರೋಕ್ತಃ ಸಾಮ್ಯೇನ ಮಧುಸೂದನ |\n\nಏತಸ್ಯ ಅಹಮ್‌ ನ ಪಶ್ಯಾಮಿ ಚಂಚಲತ್ವಾತ್‌ ಸ್ಥಿತಿಮ್‌ ಸ್ಥಿರಾಮ್‌ -- ಮಧುಸೂದನಾ, ನೀನು ಸಮದೃಷ್ಟಿಯ\nಧ್ಯಾನ ಯೋಗವನ್ನು ಹೇಳಿದೆ. ನನಗನಿಸುತ್ತದೆ: ಮನಸ್ಸು ಚಂಚಲವಾದ್ದರಿಂದ ಇದರಲ್ಲಿ ಗಟ್ಟಿಯಾಗಿ ನಿಲ್ಲುವುದು\n\nಸಾಧ್ಯವಿಲ್ಲ.\n\nಸಾತ್ವಿಕರಿಗೆ ಆನಂದವನ್ನು ಕೊಡುವ 'ಓ ಮಧುಸೂದನಾ' ಎಂದು ಅರ್ಜುನ ಶ್ರೀಕೃಷ್ಣನನ್ನು ಸಂಬೋಧಿಸಿ\nಹೇಳುತ್ತಾನೆ: “ನೀನು ಸಂಗ್ರಹವಾಗಿ ಹೇಳಿದ ಈ ಧ್ಯಾನ ಪದ್ಧತಿಯನ್ನು ನಾವು ಅಳವಡಿಸಿಕೊಳ್ಳಲು ಹೇಗೆ\nಸಾಧ್ಯ? ಧ್ಯಾನವೆಂಬುದು ಸಂಪೂರ್ಣ ಮಾನಸಿಕ ಪ್ರಕ್ರಿಯೆ. ಆದರೆ ನಮ್ಮ ಮನಸ್ಸು ಪ್ರಕ್ಷುಬ್ಧ ಮತ್ತು ಚಂಚಲ.\nಇಂತಹ ಮನಸ್ಸನ್ನು ಹಿಡಿತದಲ್ಲಿಟ್ಟು ನೀನು ಹೇಳಿದ ಸ್ಥಿರವಾದ ಈ ಧ್ಯಾನಯೋಗವನ್ನು ಸಾಧಿಸುವುದು\nಸಾಧ್ಯವಿಲ್ಲ” ಎನ್ನುತ್ತಾನೆ ಅರ್ಜುನ.",
  "6.34": "ಚಂಚಲಂ ಹಿ ಮನಃ ಕೃಷ್ಣ ಪ್ರಮಾದಿ ಬಲ ವತ್‌ ದೃಢಮ್‌ |\n\nತಸ್ಯ ಅಹಮ್‌ ನಿಗ್ರಹಮ್‌ ಮನ್ಯೇ ವಾಯೋಃ ಇವ ಸು ದುಷ್ಕರಮ್‌ -- ಕೃಷ್ಣಾ, ಬಗೆ ಚಂಚಲವಲ್ಲವೇ? ನಮ್ಮನ್ನು\nಕಂಗೆಡಿಸಿಬಿಡುವಷ್ಟು ಗಟ್ಟಿ, ಬಲಶಾಲಿ. ಅದನ್ನು ಬಿಗಿ ಹಿಡಿಯುವುದೆಂದರೆ ಗಾಳಿಯನ್ನು ಬಿಗಿ ಹಿಡಿದಂತೆ ಎಂದು\nನನ್ನ ಭಾವನೆ.\n\nಮನಸ್ಸು ತುಂಬಾ ಚಂಚಲ, ಅದು ವಿಷಯದಿಂದ ವಿಷಯಕ್ಕೆ ಹಾರುತ್ತಿರುತ್ತದೆ. ನನ್ನ ಮನಸ್ಸು ಸದಾ ನನ್ನನ್ನು\nಮಣಿಸುತ್ತಿದೆ ಆದರೆ ನಾನು ಅದನ್ನು ಮಣಿಸಲಾಗುತ್ತಿಲ್ಲ. ತನಗೆ ಬೇಕಾದಂತೆ ಇನ್ನೊಬ್ಬರನ್ನು ಬಗ್ಗು ಬಡಿಯುವ\nಸ್ವಭಾವ ಮನಸ್ಸಿನದು. ನಮ್ಮ ಭಗವದ್‌ ಸಂಕಲ್ಪವನ್ನು ಅದು ನುಚ್ಚುನೂರು ಮಾಡಿ ತನ್ನ ಸ್ವಾಧೀನ\nಮಾಡಿಕೊಂಡು ಬಿಡುತ್ತದೆ. ಇಂತಹ ಮನಸ್ಸನ್ನು ಸಾಮಾನ್ಯ ಮನುಷ್ಯ ನಿಗ್ರಹ ಮಾಡುವುದು ಹೇಗೆ? ಬೀಸುವ\nಗಾಳಿಯನ್ನು ಹೇಗೆ ಮುಷ್ಠಿಯಲ್ಲಿ ಹಿಡಿಯುವುದು ಅಸಾಧ್ಯವೋ ಹಾಗೇ ಮನಸ್ಸನ್ನು ನಿಗ್ರಹ ಮಾಡುವುದು ಅಸಾಧ್ಯ\nಎನ್ನುವುದು ನನ್ನ ಭಾವನೆ ಎನ್ನುತ್ತಾನೆ ಅರ್ಜುನ.\n\nಅರ್ಜುನನ ಈ ಪ್ರಶ್ನೆ ಭಾಗಶಃ ನಮ್ಮ ಪ್ರತಿಯೊಬ್ಬ ಓದುಗರಿಗೂ ಈ ಅಧ್ಯಾಯದ ಇಲ್ಲಿಯ ತನಕದ ಭಾಗವನ್ನು\nಓದುವಾಗ ಮನಸ್ಸಿಗೆ ಬಂದಿರುತ್ತದೆ. “ಇದೆಲ್ಲಾ ನಮ್ಮಂತವರಿಗಲ್ಲ” ಅಥವಾ “ಇದು ನಮ್ಮಿಂದ ಸಾಧ್ಯವಿಲ್ಲ”\nಎನ್ನುವುದು ಸಾಮಾನ್ಯವಾಗಿ ನಮ್ಮ ಮನಸ್ಸಿಗೆ ಬರುವ ಮೊದಲ ವಿಚಾರ. ಈ ಕಾರಣವನ್ನು ತಿಳಿದೇ ಇಲ್ಲಿ\nನಮ್ಮೆಲ್ಲರ ಪ್ರತಿನಿಧಿ “ನರ' ನಾರಾಯಣನನ್ನು ಈ ರೀತಿ ಪ್ರಶ್ನಿಸಿದ್ದಾನೆ. ಈಗ ನರನ ಈ ಪ್ರಶ್ನೆಗೆ ಕೃಷ್ಣ ಏನೆಂದು\nಉತ್ತರಿಸುತ್ತಾನೆ ಎಂದು ತಿಳಿಯುವ ಕರ್ಣಕುತೂಹಲ ನಿಮಗೆಲ್ಲರಿಗೂ ಮೂಡಿರುತ್ತದೆ. ಏಕೆಂದರೆ ನಮಗೆ ಆ\nನಮ್ಮ ಚಂಚಲ ಮನಸ್ಸನ್ನು ಮಣಿಸಬೇಕು, ಮಣಿಸಿ ಭಗವಂತನಲ್ಲಿ ನೆಲೆ ನಿಲ್ಲಿಸಬೇಕು ಎನ್ನುವ ಸಂಕಲ್ಪವಿದೆ.\nಆದರೆ ಆ ಮನಸ್ಸು ಮಹಾ ಬಲಶಾಲಿ ಎನ್ನುವ ಭಯವಿದೆ! ಬನ್ನಿ ಆ ಮಧುಸೂದನ ನಮ್ಮ ಪ್ರಶ್ನೆಗೆ ಏನೆಂದು\nಉತ್ತರಿಸಿದ ಎಂದು ಈ ಅಧ್ಯಾಯದ ಮುಂದಿನ ಭಾಗದಲ್ಲಿ ನೋಡೋಣ.",
  "6.35": "ಭಗವಾನ್‌ ಉವಾಚ-ಭಗವಂತ ಹೇಳಿದನು:\nಅಸಂಶಯಮ್‌ ಮಹಾಬಾಹೋ ಮನಃ ದುರ್ನಿಗ್ರಹಮ್‌ ಚಲಮ್‌ |\n\nಅಭ್ಯಾಸೇನ ತು ಕೌಂತೇಯ ವೈರಾಗ್ಯೇಣ ಚ ಗೃಹ್ಯತೇ -ಮಹಾವೀರಾ, ಖಂಡಿತಾ ಹೌದು; ಬಗೆ ಚಪಲವಾದದ್ದು,\nಹಿಡಿತಕ್ಕೆ ಪಿಗದ್ದು. ಅದರೆ ಕೌಂತೇಯಾ, ಮರಳಿಮರಳಿ ಯತ್ನಿ ಸುವುದರಿಂದ ಮತ್ತು ವೈರಾಗ್ಯದಿಂದ ಅದನ್ನು\nಬಿಗಿಹಿಡಿಯಬಹುದು.\n\nಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ನೀನು ಹೇಳುವುದರಲ್ಲಿ ಯಾವ ಸಂಶಯವೂ ಇಲ್ಲ. ಮನಸ್ಸನ್ನು ತಡೆ ಹಿಡಿಯುವುದು\nಸುಲಭದ ಕೆಲಸವಲ್ಲ, ಆದರೆ ಅಭ್ಯಾಸ ಮತ್ತು ವೈರಾಗ್ಯದಿಂದ ಇದನ್ನು ಕ್ರಮೇಣವಾಗಿ ಸಾಧಿಸಬಹುದು” ಎಂದು.\nನಾವು ಪ್ರಯತ್ನವಿಲ್ಲದೆ ಏನನ್ನೂ ಸಾಧಿಸಲು ಸಾಧ್ಯವಿಲ್ಲ. ಪ್ರತಿಯೊಂದಕ್ಕೂ ಪ್ರಯತ್ನ ಬೇಕು. ನಾವು ನಮ್ಮ\nಮನಸ್ಸು ಹೇಳಿದಂತೆ ಕುಣಿಯುವ ಅಭ್ಯಾಸ ಮಾಡಿಕೊಂಡು ಬಿಟ್ಟಿದ್ದೇವೆ. ಅದನ್ನು ಬಿಟ್ಟು ನಾವು ಹೇಳಿದಂತೆ\nಮನಸ್ಸು ಕೇಳುವಂತೆ ಮಾಡುವ ಪ್ರಯತ್ನವನ್ನು ನಾವೆಂದೂ ಮಾಡಿರುವುದಿಲ್ಲ. ಇಲ್ಲಿ ಕೃಷ್ಣ ವೈರಾಗ್ಯ ಮತ್ತು\nಅಭ್ಯಾಸ ಎನ್ನುವ ಎರಡು ವಿಚಾರವನ್ನು ಒತ್ತುಕೊಟ್ಟು ಹೇಳುತ್ತಾನೆ. ವೈರಾಗ್ಯ ಎಂದರೆ ಯಾವುದರ ಕಡೆ\nಮನಸ್ಸು ಹರಿಯಬಾರದೋ ಅದನ್ನು ಮನಸ್ಸಿಗೆ ಉಣಿಸದೇ(Feed) ದೂರವಿಡುವುದು. ನಮಗೆ ದೇವರು\nಯಾವುದು ಒಳ್ಳೆಯದು ಯಾವುದು ಕೆಟ್ಟದ್ದು ಎಂದು ತಿಳಿದುಕೊಳ್ಳುವ ಬುದ್ಧಿ ಕೊಟ್ಟಿದ್ದಾನೆ. ಆ ಬುದ್ಧಿಯನ್ನು\nಉಪಯೋಗಿಸಿ ನಮ್ಮ ಮನಸ್ಸನ್ನು ಕೆಟ್ಟದ್ದರಿಂದ ದೂರವಿರಿಸುವುದು. ಕೆಟ್ಟದ್ದನ್ನು ಮನಸ್ಸಿಗೆ ಪರಿಚಯ\nಮಾಡಿಕೊಡದೇ ಇರುವುದು. ಹೀಗೆ ಯಾವುದು ನಮ್ಮ ಬೆಳವಣಿಗೆಗೆ ಬಾಧಕವೋ ಅದನ್ನು ಮನಸ್ಸಿನಿಂದ\nದೂರವಿಡುವುದು ವೈರಾಗ್ಯ. ಇದರ ಜೊತೆಗೆ ನಿರಂತರವಾಗಿ ಏಕಾಗ್ರತೆಗೆ ಬೇಕಾದ ಅಭ್ಯಾಸವನ್ನು ತಪ್ಪದೇ\nಮಾಡುವುದು. ಇದರಿಂದ ನಾವು ಮನಸ್ಸನ್ನು ಖಂಡಿತವಾಗಿ ನಿಯಂತ್ರಿಸಬಹುದು ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.\nಸಾಮಾನ್ಯವಾಗಿ ನಾವು ನಮ್ಮ ಮನಸ್ಸಿಗೆ ಪ್ರತೀದಿನ ಬೇಡದ ತರಬೇತಿಯನ್ನೇ ಕೊಡುತ್ತೇವೆ. ಉದಾಹರಣೆಗೆ\nನಮ್ಮ ಅಮೂಲ್ಯವಾದ ಸಮಯದಲ್ಲಿ ದೂರದರ್ಶನದಲ್ಲಿ ಬರುವ ಯಾವುದೋ ದೈನಂದಿನ ದಾರಾವಾಹಿ,\nಸಿನಿಮ ಇತ್ಯಾದಿ ವಿಷಯದಲ್ಲಿ ನಮ್ಮ ಮನಸ್ಸನ್ನು ಸಂಪೂರ್ಣ ತೊಡಗಿಸಿಕೊಳ್ಳುತ್ತೇವೆ. ನಮಗೆ ಆಧ್ಯಾತ್ಮಿಕ\nಗ್ರಂಥಗಳನ್ನು ಓದಲು ಸಮಯವೇ ಇರುವುದಿಲ್ಲ! ದೇವರ ಪೂಜೆ ಮಾಡುವಾಗ ಕೂಡಾ ನಮಗೆ ಆ\nದಾರಾವಾಹಿಯ ಮುಂದಿನ ಭಾಗದ ಚಿಂತೆ. ನಾವು ರಾತ್ರಿ ಮಲಗುವಾಗ ಯಾವುದೋ ಕೆಟ್ಟ ಪುಸ್ತಕವನ್ನು ಓದಿ,\nಕೆಟ್ಟ ದಾರಾವಾಹಿಯನ್ನು ನೋಡಿ ಮಲಗುವ ಬದಲು, ಒಳ್ಳೆಯ ಆಧ್ಯಾತ್ಮಿಕ ಗ್ರಂಥವನ್ನು ಓದುವ ಅಭ್ಯಾಸವನ್ನು\nಮಾಡಿಕೊಂಡು ನಮಗೆ ಬೇಡವಾದ ವಿಷಯದತ್ತ ವೈರಾಗ್ಯ ಸಾಧಿಸಬೇಕು. ಇದು ಕೇವಲ ಒಂದು\nಉದಾಹರಣೆಯಷ್ಟೆ. ನಾವು ನಮ್ಮ ದೈನಂದಿನ ಚಟುವಟಿಕೆಯನ್ನು ಸೂಕ್ಷ್ಮವಾಗಿ ಗಮನಿಸಿದರೆ ನಮಗೆ ಇಂತಹ\nಸಾವಿರ ಉದಾಹರಣೆಗಳು ಸಿಗುತ್ತವೆ.\n\nಮನಸ್ಸು ತನಗೆ ತಿಳಿಯದ ವಿಷಯದತ್ತ ಹೆಚ್ಚು ಗಮನ ಕೊಡುವುದಿಲ್ಲ. ಆದರೆ ಒಮ್ಮೆ ರುಚಿ ನೋಡಿದರೆ ಅದು\nನಿಮ್ಮನ್ನು ಬಿಡುವುದಿಲ್ಲ. ಇದಕ್ಕೆ ಉತ್ತಮ ಉದಾಹರಣೆ ಮದ್ಯ ಸೇವನೆ. ಎಂದೂ ಮದ್ಯ ಸೇವನೆ ಮಾಡದವನಿಗೆ\nಮದ್ಯ ಅಸಹ್ಯವಾಗಿ ಕಾಣುತ್ತದೆ. ಆದರೆ ಒಮ್ಮೆ ಒತ್ತಾಯದಿಂದ ಬೇಡದ ಮದ್ಯವನ್ನು ಸೇವಿಸಿ ನಮ್ಮ ಮನಸ್ಸಿಗೆ\nಅದರ ಪರಿಚಯ ಮಾಡಿಸಿದಾಗ ನಮ್ಮ ಮನಸ್ಸು “ಹೇಗೂ ಒಮ್ಮೆ ಕುಡಿದಿದ್ದೀಯ ಇನ್ನೊಮ್ಮೆ ಕುಡಿದರೆ ಏನೂ\nಆಗುವುದಿಲ್ಲ-ಕುಡಿ” ಎಂದು ಹೇಳುತ್ತದೆ! ಇದರ ಪರಿಣಾಮ ಏನು ಎನ್ನುವುದನ್ನು ಇಲ್ಲಿ ವಿವರಿಸಬೇಕಾಗಿಲ್ಲ.\n\nನಮ್ಮ ಇನ್ನೊಂದು ಮಹಾ ತಪ್ಪು ಎಂದರೆ ಬೇಡದ ವಿಷಯದಲ್ಲಿ ತಲೆ ಹಾಕುವುದು. “ಯಾರೋ ಏನೋ\nಮಾಡಿದರಂತೆ”-ಈ ರೀತಿ ಒಂದು ಮಾತು ನಮ್ಮ ಕಿವಿಗೆ ಬಿದ್ದಾಗ ನಾವು ನಮಗೆ ಆ ವಿಚಾರವನ್ನು\nತಿಳಿಯುವುದರಿಂದ ಏನು ಉಪಯೋಗ ಎಂದು ಯೋಚಿಸದೆ ಆ ವಿಷಯಕ್ಕೆ ತಲೆ ಹಾಕುತ್ತೇವೆ. ಒಮ್ಮೆ ತಲೆ\nಹಾಕಿದರೆ ಮತ್ತೆ ಮನಸ್ಸು ಅದನ್ನು ಬಿಡುವುದಿಲ್ಲ. ಎಲ್ಲವನ್ನೂ ಬಿಟ್ಟು ಆ ವಿಷಯದ ಬೆನ್ನು ಹತ್ತುತ್ತದೆ. ಆದ್ದರಿಂದ\nಒಂದು ವಿಷಯಕ್ಕೆ ತಲೆ ಹಾಕುವ ಮೊದಲು ಆ ವಿಷಯದ ಬಗ್ಗೆ ಬುದ್ಧಿಪೂರ್ವಕವಾಗಿ ನಿರ್ಧಾರ ತೆಗೆದುಕೊಂಡು\nಮನಸ್ಸು ಇಲ್ಲ ಸಲ್ಲದ ವಿಚಾರದ ಹಿಂದೆ ಓಡದಂತೆ ತಡೆಹಿಡಿಯಬೇಕು. ಇದಕ್ಕೆ ಉತ್ತಮ ದೃಷ್ಟಾಂತ ಗ್ರೀಕ್‌\nದೇಶದ ಸೋಕ್ರಾಟೆಸ್‌ ಎನ್ನುವ ವಿಚಾರವಾಧಿಯ ಮೂರು ಹಂತದ ಸೋಸುವಿಕೆ ಎನ್ನುವ ಕಥೆ. ಒಮ್ಮೆ ಸೋಕ್ರಾಟೆಸ್‌ ನ ಒಬ್ಬ ಪರಿಚಯದ ವ್ಯಕ್ತಿ ಬಂದು ಸೋಕ್ರಾಟೆಸ್‌ ನಲ್ಲಿ ಈ ರೀತಿ\nಹೇಳುತ್ತಾನೆ: “ನಾನು ನಿನ್ನ ಮಿತ್ರನ ಬಗ್ಗೆ ಏನು ಕೇಳಿದೆ ಗೊತ್ತಾ?” ಎಂದು. ತಕ್ಷಣ ಸೋಕ್ರಾಟೆಸ್‌ ಹೇಳುತ್ತಾನೆ “ಸ್ವಲ್ಪ ನಿಲ್ಲು (Hold on a minute); ನೀನು ನನ್ನ\nಮಿತ್ರನ ಬಗ್ಗೆ ಏನನ್ನಾದರೂ ಹೇಳುವ ಮೊದಲು ನಾನು ಮೂರು ವಿಚಾರವನ್ನು ತಿಳಿಯ ಬಯಸುತ್ತೇನೆ.\nಮೊದಲಿಗೆ ನೀನು ಹೇಳಲು ಹೊರಟಿರುವ ವಿಚಾರದ ಬಗ್ಗೆ ನಿನಗೆ ನೈಜ ಮಾಹಿತಿ ಇದೆಯೋ?”. ಆಗ ಆ ವ್ಯಕ್ತಿ ಹೇಳುತ್ತಾನೆ: “ ಇಲ್ಲ...\nಆದರೆ ನಾನು ಈ ವಿಚಾರವನ್ನು ಕೇಳಿಸಿಕೊಂಡೆ...” ಎಂದು. ಈಗ\nಸೋಕ್ರಾಟೆಸ್‌ ಕೇಳುತ್ತಾನೆ: “ ಅಂದರೆ ನಿನಗೆ ಆ ವಿಚಾರ ಸರಿಯಾಗಿ ತಿಳಿದಿಲ್ಲ(Do you know what you are saying is true?). ನೀನು ಹೇಳಬೇಕೆಂದಿರುವ ವಿಚಾರ ತುಂಬಾ ಒಳ್ಳೆಯ ವಿಚಾರವೋ?(Is what you are about to tell me something good?)”. ಆಗ ಆ ವ್ಯಕ್ತಿ ಹೇಳುತ್ತಾನೆ: “ಅಲ್ಲ ಅದು\nಒಳ್ಳೆಯ ವಿಚಾರವಲ್ಲ-ವ್ಯತಿರಿಕ್ತ...” ಎಂದು. ಕೊನೆಯದಾಗಿ ಸೋತ್ರಾಟೆಸ್‌ ಕೇಳುತ್ತಾನೆ:\n“ನೀನು ಹೇಳಲು ಹೊರಟಿರುವ ವಿಚಾರ ನನಗೆ ಉಪಯೋಗಕ್ಕೆ ಬರುವ ವಿಚಾರವೋ?(Is what you want to tell me going to be useful to me?)”. ಆಗ ಆ ವ್ಯಕ್ತಿ ಹೇಳುತ್ತಾನೆ “ಅಲ್ಲ (No, not really)”\nಎಂದು. ಈಗ ಸೋಕ್ರಾಟೆಸ್‌ ಹೇಳುತ್ತಾನೆ “ನೀನು ಹೇಳಲು ಹೊರಟಿರುವ ವಿಚಾರ ನಿಜವಲ್ಲ, ಒಳ್ಳೆಯ\nವಿಚಾರವಲ್ಲ, ಉಪಯೋಗಕ್ಕೆ ಬರುವ ವಿಚಾರವೂ ಅಲ್ಲ. ಮತ್ತೆ ಏಕೆ ನನಗೆ ಹೇಳುತ್ತೀಯ?(Why tell it to me at all?)”.\n\nಸ್ನೆ ಹಿತರೇ, ಇಲ್ಲಿ ನಾವು ಕಲಿಯಬೇಕಾದ ವಿಚಾರವೇನೆಂದರೆ ಮನಸ್ಸ ನ್ನು ಇಲ್ಲ ಸಲ್ಲದ ವಿಚಾರದಲ್ಲಿ\nತೊಡಗಿಸುವ ಮೊದಲು ವಿಷಯವನ್ನು ಮೂರು ಬಾರಿ ಸೋಸುವುದನ್ನು ಕಲಿಯಿರಿ. ಬೇಡದ ವಿಚಾರದಲ್ಲಿ\nವೈರಾಗ್ಯವನ್ನು ತಾಳಿ ಮತ್ತು ಮನಸ್ಸನ್ನು ಏಕಾಗ್ರಮಾಡುವ ಸಾಧನೆಯನ್ನು ಮನಸ್ಸಿಗೆ ಅಭ್ಯಾಸ ಮಾಡಿಸಿ. ಈ\nಮಾರ್ಗದಲ್ಲಿ ಸಾಗಿದವರಿಗೆ ಧ್ಯಾನಯೋಗ ಎಂದೂ ಅಸಾಧ್ಯವಲ್ಲ.",
  "6.36": "ಅಸಂಯತ ಆತ್ಮನಾ ಯೋಗಃ ದುಷ್ಟ್ರಾಪಃ ಇತಿ ಮೇ ಮತಿಃ।\nವಶ್ಯ ಆತ್ಮನಾ ತು ಸತತಂ ಶಕ್ಯಃ ಆವಾಪ್ತುಮ್‌ ಅಶೇಷತಃ -ಬಗೆ ಬಿಗಿಗೊಳಿಸದವನಿಗೆ ಸಮಾಧಿ ಸಿಗುವಂತದ್ದಲ್ಲ\nಎಂದು ನನ್ನ ತೀರ್ಮಾನ. ಬಗೆಯನ್ನು ಸದಾ ಹಿಡಿತದಲ್ಲಿಟ್ಟವನು ಸಮಗ್ರವಾಗಿ ಸಮಾಧಿಯನ್ನು ಸಾಧಿಸಬಲ್ಲ.\n\nಯಾರು ತನ್ನ ಸೋಮಾರಿತನದಿಂದ, ಕೆಟ್ಟ ಲೌಕಿಕ ಅಭಿಲಾಷೆಯಿಂದ ಈ ರೀತಿ ಪ್ರಯತ್ನ ಮಾಡುವುದಿಲ್ಲವೋ\nಅವನಿಗೆ ಸಮಾಧಿ ಎಂದೂ ದಕ್ಕುವುದಿಲ್ಲ. ವೈರಾಗ್ಯ ಮತ್ತು ಅಭ್ಯಾಸವೆಂಬ ಉಪಾಯದಿಂದ ಮನಸ್ಸನ್ನು ಮಣಿಸಿ\nನಮಗೆ ಬೇಕಾದಂತೆ ಆ ಮನಸ್ಸಿನಿಂದ ಕೆಲಸವನ್ನು ಮಾಡಿಸಿಕೊಳ್ಳಬೇಕು. ಹೀಗೆ ಮಾಡಿದಾಗ ಸಮಾಧಿಯನ್ನು\nಸಾಧಿಸಬಹುದು ಎನ್ನುವ ಭರವಸೆಯನ್ನು ಕೃಷ್ಣ ಇಲ್ಲಿ ಕೊಟ್ಟಿದ್ದಾನೆ.\n\nಕೃಷ್ಣನ ಈ ಉತ್ತರದಲ್ಲಿ ನಮಗೆ ಧ್ಯಾನಕ್ಕೆ ಬೇಕಾದ ಉಪಾಯ ದೊರಕಿತು. ಆದರೆ ಈಗ ನಮ್ಮೆಲ್ಲರಿಗೆ ಇನ್ನೊಂದು\nಪ್ರಶ್ನೆ ಎದುರಾಗುತ್ತದೆ. ಅದೇನೆಂದರೆ ಸಂಸಾರದಲ್ಲಿರುವ ನಾವು ಒಂದು ವೇಳೆ ಸಾಧನೆಯ ಹಾದಿಯಲ್ಲಿ ಪೂರ್ಣ\nಸಮಾಧಿಯನ್ನು ಸಾಧಿಸದೇ ಮಧ್ಯದಲ್ಲೇ ನಿಂತಿದ್ದರೆ ಅಥವಾ ಅರ್ಧ ಸಾಧನೆಯ ನಂತರ ನನ್ನ ಈ ಜನ್ಮ\nಕೊನೆಗೊಂಡರೆ ಆಗ ನನ್ನ ಪಾಡೇನು? ಈ ಜನ್ಮದ ಸಾಧನೆ ವ್ಯರ್ಥವೋ? ನಾನು ಭಗವಂತನನ್ನು ಸೇರುವುದು\nಅಸಾಧ್ಯವೋ? ನಮ್ಮ ಈ ಪ್ರಶ್ನೆಯನ್ನೇ ಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ಅರ್ಜುನ ಕೃಷ್ಣನಲ್ಲಿ ಕೇಳುತ್ತಾನೆ.",
  "6.37": "ಅರ್ಜುನ ಉವಾಚ |\nಅಯತಿಃ ಶ್ರದ್ಧಯೋಪೇತೋ ಯೋಗಾಚ್ಚಲಿತಮಾನಸಃ |\n\nಅಪ್ರಾಪ್ಯ ಯೋಗಸಂಸಿದ್ಧಿಂ ಕಾಂ ಗತಿಂ ಕೃಷ್ಣ ಗಚ್ಛತಿ 1೩೭॥\n\nಅರ್ಜುನಃ ಉವಾಚ-ಅರ್ಜುನ ಕೇಳಿದನು:\n\nಅಯತಿಃ ಶ್ರದ್ಧಯಾ ಉಪೇತಃ ಯೋಗಾತ್‌ ಚಲಿತ ಮಾನಸಃ ।\n\nಅಪ್ರಾಪ್ಯ ಯೋಗಸಂಸಿದ್ಧಿಮ್‌ ಕಾಮ್‌ ಗತಿಮ್‌ ಕೃಷ್ಣ ಗಚ್ಛತಿ -ಕೃಷ್ಣಾ, ಶ್ರದ್ಧೆಯಿದೆ- ಪ್ರಯತ್ನಿಸುವುದಾಗಲಿಲ್ಲ.\nಧ್ಯಾನಯೋಗದಿಂದ ಬಗೆ ಕದಲಿದೆ. ಯೋಗಸಿದ್ಧಿಯನ್ನು ಪಡೆಯಲಾಗದ ಇಂತವನ ಪಾಡೇನು?\n\nಯೋಗದ ಸಾಧನೆಯಲ್ಲಿ ಸಾಧನೆ ಮಾಡಿದ, ಧ್ಯಾನ ಮಾಡುವುದಕ್ಕೂ ಪ್ರಯತ್ನ ಮಾಡಿದ, ಒಂದು ಹಂತದವರೆಗೆ\nಶ್ರದ್ದೆಯಿಂದ ಏಕಾಗ್ರತೆಗೆ ಪ್ರಯತ್ನಿ ಸಿದ, ಯಾವುದೋ ಕಾರಣದಿಂದ ಪೂರ್ಣ ಗುರಿ ತಲುಪಲಿಲ್ಲ-ಅಂತವನ\nಪಾಡೇನು? ಇಂತವರಿಗೆ ಸಿದ್ಧಿ ಲಭಿಸದೇ?",
  "6.38": "ಕಚ್ಚಿತ್‌ ನ ಉಭಯ ವಿಭ್ರಷ್ಟಃ ಛಿನ್ನ ಅಭ್ರಮ್‌ ಇವ ನಶ್ಯತಿ |\nಅಪ್ರತಿಷ್ಠಃ ಮಹಾಬಾಹೋಃ ವಿಮೂಢಃ ಬ್ರಹ್ಮಣಃ ಪಥಿ -ಓ ಮಹಾಬಾಹೋ, ನೆಲೆಗಾಣದೆ, ಭಗವಂತನ\nದಾರಿಯಲ್ಲಿ ಗುರಿತಪ್ಪಿ ದ ಅವನು ಇಲ್ಲೂ ಇಲ್ಲದೆ ಅಲ್ಲೂ ಸಲ್ಲದೆ ತುಂಡು ಮೋಡದಂತೆ ಮರೆಯಾಗುವನೆ?\n\nಇಂತವರ ಬದುಕು ಇಹವೂ ಇಲ್ಲದೆ, ಪರವೂ ಇಲ್ಲದೆ, ಒಂದು ತುಣುಕು ಮೋಡದಂತೆ ಆ ಕಡೆ ನೆರಳೂ ಆಗದೆ,\nಈಚೆ ಮಳೆಯೂ ಸುರಿಸದೆ ಯಾವುದಕ್ಕೂ ಉಪಯೋಗವಿಲ್ಲದೆ ವ್ಯರ್ಥವಾಗಿ ಹೋಗುವುದೋ? ಜ್ಞಾನ ಬಲ\nಇಚ್ಛಾ ಸ್ವರೂಪನಾದ(ಮಹಾಬಾಹೋಃ) ನೀನು ಅಂತಹ ವಯವಿಭ್ರಷ್ಟರನ್ನು ಏನು ಮಾಡುತ್ತೀಯ?\n\nಏತನ್ಮೇ ಸಂಶಯಂ ಕೃಷ್ಣ ಚ್",
  "6.39": "ಏತನ್ಮೇ ಸಂಶಯಂ ಕೃಷ್ಣ ಛೇತ್ತುಮರ್ಹಸ್ಯಶೇಷತಃ ।\nತ್ವದನ್ಯಃ ಸಂಶಯಸ್ಯಾಸ್ಯ ಛೇತ್ತಾ ನ ಹ್ಯುಪಪದ್ಯತೇ ॥\n\n'ಕೃಷ್ಣಾ, ನನ್ನ ಈ ಸಂಶಯವನ್ನು ಪೂರ್ತಿಯಾಗಿ ಪರಿಹರಿಸಲು ನೀನೇ ಸಮರ್ಥನು. ನಿನ್ನನ್ನು ಬಿಟ್ಟರೆ ಈ ಸಂಶಯವನ್ನು ಪರಿಹರಿಸಬಲ್ಲವನು ಬೇರಾರೂ ಇಲ್ಲ.'\n\nಅರ್ಜುನನ ವಿನಮ್ರ ಒಪ್ಪಿಗೆ — ಭಗವಂತನೊಬ್ಬನೇ ಉತ್ತರಿಸಲು ಶಕ್ತ. 'ತ್ವದನ್ಯಃ' — ನಿನ್ನನ್ನು ಬಿಟ್ಟು. 'ನ ಹ್ಯುಪಪದ್ಯತೇ' — ಸಾಧ್ಯವಿಲ್ಲ. ಪ್ರಶ್ನೆಯ ಕೊನೆಯಲ್ಲಿ ಭಕ್ತನ ಶರಣಾಗತಿ — ಇದು ಯೋಗ್ಯವಾದ ಮುಕ್ತಾಯ.",
  "6.40": "ಭಗವಾನ್‌ ಉವಾಚ-ಭಗವಂತ ಹೇಳಿದನು:\n\nಪಾರ್ಥ ನ ಏವ ಇಹ ನ ಅಮುತ್ರ ವಿನಾಶಃ ತಸ್ಯ ವಿದ್ಯತೇ |\n\nನ ಹಿ ಕಲ್ಯಾಣಕೃತ್‌ ಕಶ್ಚಿತ್‌ ದುರ್ಗತಿಮ್‌ ತಾತ ಗಚ್ಛತಿ- ಪಾರ್ಥಾ, ಅವನ ಸಾಧನೆ ವ್ಯರ್ಥವಲ್ಲ, ಇಹದಲ್ಲಿ ಮತ್ತು\nಪರದಲ್ಲಿ. ಅಪ್ಪಾ, ಒಳಿತನ್ನು ಮಾಡುವವನು ಎಂದೂ ಕೇಡನ್ನು ಪಡೆಯುವುದಿಲ್ಲ.\n\nಅರ್ಜುನನ ಪ್ರಶ್ನೆಗೆ ಕೃಷ್ಣನ ಉತ್ತರ ದೊಡ್ಡ ಭರವಸೆ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಸಾಧನೆಯ ದಾರಿಯಲ್ಲಿ ಸಾಗಿದವರು\nಇಹದಲ್ಲಿ ಅಥವಾ ಪರದಲ್ಲಿ ಏನನ್ನೂ ಕಳೆದುಕೊಳ್ಳುವುದಿಲ್ಲ. ಓ ನನ್ನ ಪ್ರೀತಿಯ ಮಿತ್ರನೇ, ಒಳ್ಳೆಯದನ್ನು\nಮಾಡಿದವರು ಎಂದೂ ಕೆಟ್ಟದ್ದನ್ನು ಪಡೆಯುವುದಿಲ್ಲ. ಇದು ಪ್ರಕೃತಿಯ ನಿಯಮ” ಎಂದು. ಇಲ್ಲಿ ಕೃಷ್ಣ\nಅರ್ಜುನನನ್ನು ಪಾರ್ಥಾ ಎಂದು ಸಂಬೋಧಿಸಿದ್ದಾನೆ. ಪಾರ್ಥ ಎಂದರೆ ಪಾರವನ್ನು(ದಡವನ್ನು) ತಿಳಿದವನು.\nಸಾಧನೆಯ ಹಾದಿಯಲ್ಲಿ ಹೆಜ್ಜೆ ಇಟ್ಟವನು ಒಮ್ಮೆಗೇ ಭಗವಂತನನ್ನು ಕಾಣದಿದ್ದರೂ ಕೂಡಾ, ಆತ ಎಂದೂ\nಮಧ್ಯದಲ್ಲಿ ಮುಳುಗುವುದಿಲ್ಲ. ಆತ ಸಾಧನೆಯ ಆಚೆ ದಡವನ್ನು ಸೇರಿಯೇ ಸೇರುತ್ತಾನೆ. ಒಳ್ಳೆಯದನ್ನು\nಮಾಡಿದವರಿಗೆ ಒಳ್ಳೆಯ ಮಾರ್ಗವನ್ನು ತುಳಿದವರಿಗೆ ಎಂದೂ ಕೆಟ್ಟದ್ದಾಗುವುದಿಲ್ಲ. ನಮ್ಮಲ್ಲಿ ಕೆಲವರು\n\nಹೇಳುವುದಿದೆ: “ನಾನು ನನ್ನ ಜೀವನದಲ್ಲಿ ಎಂದೂ ಕೆಟ್ಟ ಕೆಲಸ ಮಾಡಿಲ್ಲ, ಯಾವತ್ತೂ ಒಬ್ಬರಿಗೆ ಕೇಡನ್ನು\nಬಯಸಲಿಲ್ಲ, ಆದರೆ ಏಕೆ ದೇವರು ನನಗೆ ಹೀಗೆ ಮಾಡಿದ?” ಎಂದು. ನಾವು ಜೀವನದಲ್ಲಿ ಕೆಟ್ಟದ್ದನ್ನು ಮಾಡಿಲ್ಲ,\nಕೆಟ್ಟದ್ದನ್ನು ಎಣಿಸಿಲ್ಲ' ಎನ್ನುವುದು ಕೇವಲ ಈ ಜನ್ಮಕ್ಕೆ ಸೀಮಿತ. ಆದರೆ ಜೀವದ ಗತಿ ಅನಾದಿ ಅನಂತ. ಅದು\nಜನ್ಮದಿಂದ ಜನ್ಮಕ್ಕೆ ಹರಿದು ಬರುವ ಪ್ರವಾಹ. ನಾವು ಈ ಜನ್ಮದಲ್ಲಿ ಒಂದು ದುರಂತ ಅಥವಾ ಕಷ್ಟಕ್ಕೆ\nಒಳಗಾದರೆ ಅದಕ್ಕೆ ಕಾರಣ ಭೂತವಾಗಿರುವಂತಹ ಇನ್ನೊಂದು ಕ್ರಿಯೆ ನಮ್ಮಿಂದ ನಡೆದಿರಲೇ ಬೇಕು. ಕೆಟ್ಟದ್ದನ್ನು\nಮಾಡದವನು ಕೆಟ್ಟದ್ದನ್ನು ಪಡೆಯುವುದಿಲ್ಲ. ಒಳ್ಳೆಯದನ್ನು ಮಾಡಿದವನು ಒಳ್ಳೆಯದನ್ನು ಪಡೆಯದೇ\nಇರುವುದಿಲ್ಲ. ಇದು ಸಾರ್ವಕಾಲಿಕ ಸತ್ಯ. ಇದಕ್ಕೆ ಅಪವಾದವೇ ಇಲ್ಲ. ಅದು ಹೇಗೆ ಎನ್ನು ವುದನ್ನು ಕೃಷ್ಣ ಮುಂದೆ\nವಿವರಿಸುತ್ತಾನೆ.\n",
  "6.41": "ಪ್ರಾಪ್ಯ ಪುಣ್ಯಕೃತಾಮ್‌ ಲೋಕಾನ್‌ ಉಪಿತ್ವಾ ಶಾಶ್ವತೀಃ ಸಮಾಃ ।\nಶುಚೀನಾಮ್‌ ಶ್ರೀಮತಾಮ್‌ ಗೇಹೇ ಯೋಗ ಭ್ರಷ್ಟಃ ಅಭಿಜಾಯತೇ-ಇಂತಹ ಯೋಗ ಭ್ರಷ್ಟ ನು ಪುಣ್ಯವಂತರ\nಲೋಕಗಳನ್ನು ಪಡೆದು ಅಲ್ಲಿ ಬಹಳ ಕಾಲ ನೆಲೆಸಿ ಅನಂತರ ನಿರ್ಮಲರೂ ಸಿರಿವಂತರೂ ಆದವರ ಮನೆಯಲ್ಲಿ\n\nಹುಟ್ಟುತ್ತಾನೆ.\n\nಯೋಗಾಭ್ಯಾಸ ಮಾಡಿ, ಭಗವಂತನ ಧ್ಯಾನಕ್ಕೆ ಪ್ರಯತ್ನಿ ಸಿ, ಕೆಲವು ಮೆಟ್ಟ ಲನ್ನೆ ೀರಿ ಯಾವುದೋ ಕಾರಣದಿಂದ,\nಮನೋವಿಕ್ಷೇಪದಿಂದ ಅಥವಾ ಆಯುಸ್ಸು ಮುಗಿದುದರಿಂದ, ಅಲ್ಲೇ ಅದನ್ನು ನಿಲ್ಲಿಸಿದವನ ಸಾಧನೆ ಎಂದೂ\nವ್ಯರ್ಥವಲ್ಲ. ಇದು ಏಕೆ ಎನ್ನುವುದನ್ನು ಕೃಷ್ಣ ಹಿಂದಿನ ಅಧ್ಯಾಯದಲ್ಲೇ (ಅ-೨; ಶ್ಲೋ-೪೦) ವಿವರಿಸಿದ್ದಾನೆ. ಅದಕ್ಕೆ\nಒತ್ತು ಕೊಟ್ಟು ಇಲ್ಲಿ ಮತ್ತೆ ವಿವರಿಸುತ್ತಾನೆ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ ಸಾಧನೆ ಮಧ್ಯದಲ್ಲಿ ನಿಂತು ಹೋದರೆ ಏನೂ\nತೊಂದರೆ ಇಲ್ಲ. ಏಕೆಂದರೆ ಅಂತವನು ದೇಹತ್ಯಾಗ ಮಾಡಿದ ಮೇಲೆ ಪುಣ್ಯವನ್ನು ಗಳಿಸಿದವರು ಪಡೆಯುವಂತಹ\nಲೋಕವನ್ನು ಪಡೆಯುತ್ತಾನೆ. ಬಹಳ ಕಾಲದ ತನಕ ಅಲ್ಲಿ ಸುಖವನ್ನು ಅನುಭವಿಸಿ, ಮತ್ತೆ ಭೂಮಿಯಲ್ಲಿ\nಸ್ವಚ್ಛವಾದ ಶ್ರೀಮಂತ ವೇದಜ್ಞರ ಮನೆಯಲ್ಲಿ ಹುಟ್ಟುತ್ತಾನೆ. ಆತನಿಗೆ ಯಾವುದೇ ಐಹಿಕ ಭೋಗದ ಕೊರತೆ\nಕಾಡದು. ಯೋಗಸಾಧನೆಗೆ ಬೇಕಾದ ಅತ್ಯುತ್ತಮ ವಾತಾವರಣ ಅವನಿಗೆ ದೊರೆಯುತ್ತದೆ.\n",
  "6.42": "ಅಥವಾ ಯೋಗಿನಾಮ್‌ ಏವ ಕುಲೇ ಭವತಿ ಧೀಮತಾಮ್‌ ।\nಏತತ್‌ ಹಿ ದುರ್ಲಭ ತರಮ್‌ ಲೋಕೇ ಜನ್ಮ ಯತ್‌ ಈದೃಶಮ್‌... ಅಥವಾ ಬಲ್ಲವರಾದ ಯೋಗಿಗಳ\nಮನೆತನದಲ್ಲಿ ಹುಟ್ಟುತ್ತಾನೆ. ಲೋಕದಲ್ಲಿ ಈ ಬಗೆಯ ಹುಟ್ಟು ತುಂಬಾ ದುರ್ಲಭವಾದದ್ದು.\n\nಮುಂದುವರಿದು ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: ಯೋಗಸಾಧಕರಲ್ಲದಿದ್ದರೆ, ಯೋಗ ಸಿದ್ಧರ ಮನೆಯಲ್ಲಿ ಆತ ಜನಿಸುತ್ತಾನೆ.\nಇದರಿಂದ ಗರ್ಭದಿಂದಲೇ ಆತನಿಗೆ ಯೋಗದ ದೀಕ್ಷೆಯಾಗುತ್ತದೆ. ಹಿಂದಿನ ಜನ್ಮದಲ್ಲಿ ಆತ ಸಾಧನೆಯ ಯಾವ\nಮೆಟ್ಟಿಲನ್ನು ಹತ್ತಿದ್ದನೋ ಆ ಮೆಟ್ಟಿಲನ್ನು ಸುಲಭವಾಗಿ ಆತ ತಲುಪಿ ಅಲ್ಲಿಂದ ಮುಂದಿನ ಸಾಧನೆ ಮಾಡುವ\nಅವಕಾಶ ಅವನಿಗೆ ಸಿಗುತ್ತದೆ. ಇದು ಅಧ್ಯಾತ್ಮ ಸಾಧನೆಯಲ್ಲಿನ ವಿಶೇಷ. ಒಂದು ಜನ್ಮದಲ್ಲಿ ಎರಡು ಮೆಟ್ಟಿಲು\nಹತ್ತಿದರೆ ಮುಂದಿನ ಜನ್ಮದಲ್ಲಿ ನೇರವಾಗಿ ಮೂರನೇ ಮೆಟ್ಟಿಲಿಗೆ ಹೆಜ್ಜೆ. ಈ ಕಾರಣದಿಂದ ಯಾವ ಸಾಧನೆಯೂ\nವ್ಯರ್ಥವಲ್ಲ- ಈ ಬಗ್ಗೆ ಎಂದೂ ನಿರಾಶೆಪಡಬೇಕಾಗಿಲ್ಲ. ಈ ರೀತಿ ಪಕ್ವವಾದ ಜೀವ ಯೋಗಸಿದ್ಧರ ಮನೆಯಲ್ಲಿ\nಹುಟ್ಟುವುದರಿಂದ ಆತನಿಗೆ ಅಲ್ಲಿ ಅನುವಂಶೀಯ ಸಾತ್ವಿಕ ಸೆಳೆತ (genetic forces) ಮತ್ತು ಅದಕ್ಕೆ ಬೇಕಾದ\nವಾತಾವರಣ(Environmental forces) ಸಿಗುತ್ತದೆ. ಮತ್ತು ಆತ ಅಲ್ಲಿ ತನ್ನ ಸಾಧನೆಯನ್ನು\nಮುಂದುವರಿಸುತ್ತಾನೆ. ಲೋಕದಲ್ಲಿ ಯೋಗಸಿದ್ಧರ ಮನೆಯಲ್ಲಿ ಹುಟ್ಟು ಬಹಳ ದುರ್ಲಭ. ಸಾಧನೆಯ ಹಾದಿಯಲ್ಲಿ\nಎತ್ತರಕ್ಕೇರಿದವರಿಗೆ ಮಾತ್ರ ಈ ಭಾಗ್ಯ.\n",
  "6.43": "ತತ್ರ ತಮ್‌ ಬುದ್ಧಿಸಂಯೋಗಮ್‌ ಲಭತೇ ಪೌರ್ವ ದೈಹಿಕಮ್‌ |\nಯತತೇ ಚ ತತಃ ಭೂಯಃ ಸಂಸಿದ್ದೌ ಕುರುನಂದನ-- ಈ ಜನ್ಮದಲ್ಲೂ ಹಿಂದಿನ ಜನ್ಮದ ವಿವೇಕದ ನಂಟನ್ನು\nಮರಳಿ ಪಡೆಯುತ್ತಾನೆ. ಕುರುನಂದನಾ, ಮತ್ತೆ ಮರಳಿ ಸಿದ್ಧಿಗಾಗಿ ಪ್ರಯತ್ನಿಸುತ್ತಾನೆ.\n\nಹಿಂದಿನ ಜನ್ಮದಲ್ಲಿ ಅವನು ಏನು ಸಾಧನೆ ಮಾಡಿದ್ದ ಅವೆಲ್ಲವೂ ಸುಪ್ಪಪ್ರಜ್ಞೆಯಲ್ಲಿ ಹುದುಗಿದ್ದು ಅದಕ್ಕೆ\nಅನುಗುಣವಾದ ವಾತಾವರಣ ಸಿಕ್ಕ ತಕ್ಷಣ ಅದು ಜಾಗೃತವಾಗುತ್ತದೆ. ಈ ಜನ್ಮದ ಬೆಳವಣಿಗೆ ಹಿಂದಿನ ಜನ್ಮದ\nಬೆಳವಣಿಗೆಯ ಉತ್ತರಾರ್ಧವಾಗುತ್ತದೆ. ಒಂದು ವೇಳೆ ಹಿಂದಿನ ಜನ್ಮದಲ್ಲಿ ಹೆಚ್ಚು ಬೆಳವಣಿಗೆ ಆಗದೇ ಇದ್ದಿದ್ದರೆ\nಇಲ್ಲಿ ಅದನ್ನು ಪ್ರಾರಂಭಿಸಬೇಕೇ ಹೊರತು ಅದಕ್ಕಾಗಿ ಗಾಬರಿಪಡುವ ಅವಶ್ಯಕತೆ ಇಲ್ಲ. ಪೂರ್ವ ಜನ್ಮದ\nಸಂಸ್ಕಾರ ಸದಾ ನಮ್ಮೊಂದಿಗಿರುತ್ತದೆ ಹಾಗೂ ಆ ಸಂಸ್ಕಾರದೊಂದಿಗೆ ನಾವು ಸಾಧನೆಯ ಹಾದಿಯಲ್ಲಿ\nಮುಂದುವರಿಯಬೇಕು. ಧ್ಯಾನಯೋಗವೆಂಬುವುದು ಒಂದು ಜನ್ಮದ ಸಾಧನೆಯಲ್ಲ.\n",
  "6.44": "ಪೂರ್ವ ಅಭ್ಯಾಸೇನ ತೇನ ಏವ ಹ್ರಿಯತೇ ಹಿ ಅವಶಃ ಅಪಿಸಃ।\n\nಜಿಜ್ಞಾಸುಃ ಅಪಿ ಯೋಗಸ್ಯ ಶಬ್ದಬ್ರಹ್ಮ ಅತಿವರ್ತತೇ -- ಹಿಂದಿನ ಅಭ್ಯಾಸ ಬಲದಿಂದ ಅವನಿಗರಿವಿಲ್ಲದೆಯೇ,\nಅವನ ಬಗೆ ಅತ್ತ ಹರಿಯುತ್ತದೆ. ಧ್ಯಾನಯೋಗವನ್ನು ತಿಳಿಯಬಯಸಿದವನು ಕೂಡಾ ಶಬ್ದಬ್ರಹ್ಮದಾಚೆಗಿರುವ\nಪರಬ್ರಹ್ಮನನ್ನು ಸೇರುತ್ತಾನೆ.\n\nಒಂದು ವೇಳೆ ವೇದಜ್ಞರ ಮನೆಯಲ್ಲಿ ಹುಟ್ಟದೇ ಇದ್ದರೂ ಕೂಡಾ ಹಿಂದಿನ ಜನ್ಮದ ಸಾಧನೆಯ ಫಲದಿಂದ\nನಮಗರಿವಿಲ್ಲದಂತೆ ನಮ್ಮ ಮನಸ್ಸು ಸಾಧನೆಯತ್ತ ಹರಿಯುತ್ತದೆ. ಪ್ರಹ್ಲಾದದನ ಮತ್ತು ಪಿಂಗಳೆಯ ಕಥೆ ಇದಕ್ಕೆ\nಉತ್ತಮ ದೃಷ್ಟಾಂತ. ಅಂತರಂಗದಲ್ಲಿ ಸದಾ ಅಧ್ಯಾತ್ಮದ ಬಗ್ಗೆ ತುಡಿತ, ಅತ್ಯಂತ ಉತ್ಕಟವಾದ ಕಳಕಳಿ ಇದ್ದರೆ\nಅವರು ಶಾಸ್ತ್ರ ಓದಿದವರನ್ನೂ ಮೀರಿ ಎತ್ತರಕ್ಕೇರುತ್ತಾರೆ.",
  "6.45": "ಪ್ರಯತ್ನಾತ್‌ ಯತಮಾನಃ ಟು ಯೋಗೀ ಸಂಶುದ್ಧ ಕಿಲ್ಬಿಷಃ |\n\nಅನೇಕ ಜನ್ಮಸಂಸಿದ್ಧಃ ತತಃ ಯಾತಿ ಪರಾಮ್‌ ಗತಿಮ್‌-- ಧ್ಯಾನದಲ್ಲಿ ತೊಡಗುವ ಸಾಧಕ ಪ್ರಯತ್ನದ\nಫಲವಾಗಿ ಬಗೆಯ ಕಿಲುಬು ಕಳೆದುಕೊಂಡು ಅನೇಕ ಜನ್ಮಗಳ ಸಾಧನೆಯಿಂದ ಸಿದ್ಧಿ ಪಡೆದು ಹಿರಿಯ ನೆಲೆಯಾದ\nಭಗವಂತನನ್ನು ಸೇರುತ್ತಾನೆ.\n\nಹಿಂದೆ ಹೇಳಿದಂತೆ ನಮ್ಮ ಸಾಧನೆ ಅನೇಕ ಜನ್ಮಗಳದ್ದು. ಮೊದಲು ನಮ್ಮಲ್ಲಿ ಇಚ್ಛೆ ಹುಟ್ಟಿತು, ಅದರಿಂದ ಆ ಇಚ್ಛೆ\nಪೂರ್ಣವಾಗುವ ವಾತವರಣವನ್ನು ಮುಂದಿನ ಜನ್ಮದಲ್ಲಿ ಭಗವಂತ ಕೊಟ್ಟ, ಅಲ್ಲಿ ಪ್ರಯತ್ನ ಮಾಡಿ ಒಳಗಿನ ಕೊಳೆ\nತೊಳೆಯಿತು, ಸಾಧನೆಯಿಂದ ಸ್ವಚ್ಛವಾದ ಜ್ಞಾನ ಬಂತು. ಈ ಜ್ಞಾನ ಮತ್ತು ಸಾಧನೆಯಿಂದ ಅನೇಕ ಜನ್ಮಗಳ\nನಂತರ ಶಬ್ದಬ್ರಹ್ಮನನ್ನು ಮೀರಿ ಭಗವಂತನನ್ನು ಕಾಣಲು ಸಾಧ್ಯ. ಹೀಗೆ ಅಂತರಂಗದಲ್ಲಿ ಉತ್ಕಟವಾದ\nಕಳಕಳಿಯುಳ್ಳ ಜಿಜ್ಞಾಸು ಶಾಸ್ತ್ರ ಪಂಡಿತರನ್ನು ಮೀರಿ ಮೋಕ್ಷವನ್ನು ತಲುಪಬಲ್ಲ.\n\nಸಾಧನೆಯಲ್ಲಿ ಬಹಳ ಮುಖ್ಯವಾದದ್ದು ಅಂತರಂಗ ಪ್ರಪಂಚದ ಸಾಧನೆ. ಹೊರಗಡೆ ಸ್ನಾನ, ಪೂಜೆ, ಹೋಮ,\nಹವನ, ಏನೇ ಮಾಡಿದರೂ ಕೂಡಾ, ಅದಕ್ಕಿಂತ ಮಿಗಿಲಾದದ್ದು ಅಂತರಂಗ ಪ್ರಪಂಚ. ಇದನ್ನು ಮುಂದಿನ\nಶ್ಲೋಕದಲ್ಲಿ ವಿವರಿಸುತ್ತಾನೆ ಕೃಷ್ಣ.\n",
  "6.46": "ತಪಸ್ವಿಭ್ಯಃ ಅಧಿಕಃ ಯೋಗೀ ಜ್ಞಾನಿಭ್ಯಃ ಅಪಿ ಮತಃ ಅಧಿಕಃ |\n\nಕರ್ಮಿಭ್ಯಃ ಚ ಅಧಿಕಃ ಯೋಗೀ ತಸ್ಮಾತ್‌ ಯೋಗೀ ಭವ ಅರ್ಜುನ--ಧ್ಯಾನ ಯೋಗದ ಸಾಧಕ ಉಪವಾಸ\nಮೊದಲಾದ ವ್ರತಸಾಧಕರಿಗಿಂತ ಮಿಗಿಲು; ಬರಿಯ ಧ್ಯಾನಯೋಗದ ಬಗೆಯನ್ನು ಬಲ್ಲವರಿಗಿಂತಲೂ ಮಿಗಿಲು\nಎನ್ನುವುದು ತೀರ್ಮಾನ. ಕರ್ಮ ಯೋಗಿಗಳಿಗಿಂತಲೂ ಮಿಗಿಲು. ಆದ್ದರಿಂದ ಓ ಅರ್ಜುನಾ, ನೀನು\nಧ್ಯಾನಯೋಗಿಯಾಗು.\n\nಯಾರು. ಅಂತರಂಗದಲ್ಲಿ ಏಕಾಗ್ರವಾಗಿ ಭಗವಂತನನ್ನು ಧ್ಯಾನಿಸಬಲ್ಲನೋ, ಅವನು ತಪಸ್ಸು\nಮಾಡುವವನಿಗಿಂತ ದೊಡ್ಡವ ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಇಲ್ಲಿ ತಪಸ್ಸು ಎಂದರೆ ನಾವು ಮಾಡುವ ವೃತಾಚರಣೆ. ದೇಹ\nದಂಡನೆ, ಏಕಾದಶಿ ಉಪವಾಸ, ಬ್ರಹ್ಮಚರ್ಯಪಾಲನೆ ಇತ್ಯಾದಿ. ಬಾಹ್ಯವಾದ ನೂರಾರು ವೃತಾಚರಣೆ,\nಹೋಮ-ಹವನ ಮಾಡುವವರಿಗಿಂತಲೂ ಅಂತರಂಗದಲ್ಲಿ ಧ್ಯಾನ ಮಾಡತಕ್ಕವನು ಭಗವಂತನಿಗೆ ಹೆಚ್ಚು ಪ್ರಿಯ.\nಅವನು ಜ್ಞಾನಿಗಳಿಗಿಂತಲೂ ದೊಡ್ಡವನು ಎನ್ನು ತ್ತಾನೆ ಕೃಷ್ಣ. ಅಂದರೆ ಧ್ಯಾನದ ಬಗ್ಗೆ, ಶಾಸ್ತ್ರದ ಬಗ್ಗೆ ಕೇವಲ\nತಿಳಿದಿರುವವರಿಗಿಂತ ಧ್ಯಾನ ಮಾಡುವವನು ದೊಡ್ಡವನು. ಇಂದು ಅಧ್ಯಾತ್ಮದ ಬಗ್ಗೆ ಮಾತನಾಡುವವರು\nಸಿಗುತ್ತಾರೆ, ಹೊರತು ನಿಜವಾದ ಧ್ಯಾನ ಯೋಗಿಗಳು ಸಿಗುವುದು ಅತೀ ವಿರಳ(There are nowadays professors of philosophy, but not philosophers - Henry David Thoreau, Walden).\n\nನಮ್ಮಲ್ಲಿ ಕೆಲವರು ಕರ್ಮಟರು. ಯಜ್ಞ-ಯಾಗ ಮಾಡುವುದು, ಅಗ್ನಿ ಮುಖೇನ ಭಗವಂತನ ಆರಾಧನೆ\nಮಾಡುವವರು. ಅಂತರಂಗದಲ್ಲಿ ಭಗವಂತನನ್ನು ಕಾಣುವುದಕ್ಕೋಸ್ಕರ ಈ ಕರ್ಮ. ಇದೇ ರೀತಿ ಪ್ರತಿಮಾಪೂಜೆ.\nನಮ್ಮ ಪೂಜೆ ಕೇವಲ ದೇವರ ಪ್ರತಿಮೆಗೆ ಮೀಸಲಾಗದೇ ಅದು ಅಂತರಂಗದಲ್ಲಿ ಭಗವಂತನನ್ನು ಕಾಣಲು\nಸಹಾಯ ಮಾಡುವ ಸಂಕೇತ ಎನ್ನುವ ಜ್ಞಾನ ನಮಗಿರಬೇಕು. ಮಾನಸ ಪೂಜೆ ಇಲ್ಲದೇ ಬಾಹ್ಯ ಪೂಜೆ ಪೂಜೆಯೇ\nಅಲ್ಲ. ಆದ್ದರಿಂದ ಬರೇ ಕರ್ಮಟನಾಗಿ. ಬಾಹ್ಯಪೂಜೆ ಮಾಡುವವನಿಗಿಂತ ಮಾನಸ ಪೂಜೆ ಮಾಡುವ\nಧ್ಯಾನಯೋಗಿ ದೊಡ್ಡವ. “ ಆದ್ದರಿಂದ ನೀನು ಜೀವನದಲ್ಲಿ ಧ್ಯಾನಯೋಗಿಯಾಗು, ಅಂತರಂಗದ ಧ್ಯಾನದಲ್ಲಿ\nತೊಡಗು. ಆ ಧ್ಯಾನದಲ್ಲಿ ತೊಡಗಿದ ಮೇಲೆ ನಿನ್ನ ಬಾಹ್ಯಕರ್ಮಗಳು ನಿನಗೆ ಲೇಪವಾಗುವುದಿಲ್ಲ. ಆಗ ಯುದ್ಧವೂ\nಕೂಡಾ ಭಗವದ್‌ ಪೂಜೆಯಾಗುತ್ತದೆ” ಎನ್ನುವುದು ಅರ್ಜುನನಿಗೆ ಕೃಷ್ಣನ ಸಂದೇಶ.\n",
  "6.47": "ಯೋಗಿನಾಮ್‌ ಅಪಿ ಸರ್ವೇಷಾಮ್‌ ಮತ್‌ ಗತೇನ ಅಂತಃ ಆತ್ಮನಾ ।\nಶ್ರದ್ಧಾವಾನ್‌ ಭಜತೇ ಯಃ ಮಾಮ್‌ ಸಃ ಮೇ ಯುಕ್ತ ತಮಃ ಮತಃ -ನನ್ನಲ್ಲಿ ಒಳಬಗೆಯನ್ನಿ ರಿಸಿ ಶ್ರದ್ಧೆಯಿಂದ\nನನ್ನನ್ನು ಸೇವಿಸುವವನು ಇತರ ಎಲ್ಲಾ ಧ್ಯಾನಯೋಗಿಗಳಿಗಿಂತಲೂ ಹಿರಿಯ ಯೋಗಿ ಎಂದು ನನ್ನ ತೀರ್ಮಾನ.\n\nಧ್ಯಾನವನ್ನು ಮಾಡುವಾಗ ನಾವು ಮನಸ್ಸನ್ನು ಯಾವುದರ ಮೇಲೆ ಕೂಡಾ ಏಕಾಗ್ರ ಮಾಡಿ ಧ್ಯಾನ\nಮಾಡಬಹುದು. ಕೆಲವರು ಅನೇಕ ಕ್ಷುದ್ರ ದೇವತೆಗಳು, ಭೂತ-ಪ್ರೇತಗಳನ್ನು ಉಪಾಸನೆ ಮಾಡುವವರಿದ್ದಾರೆ.\n\nಆದರೆ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಯಾರು ಭಗವಂತನಲ್ಲೇ ಮನಸ್ಸನ್ನಿಟ್ಟು ಧ್ಯಾನ ಮಾಡುತ್ತಾರೋ ಅವರು ಎಲ್ಲರಿಗಿಂತ\nಹಿರಿಯ ಯೋಗಿ” ಎಂದು. ಭಗವಂತನನ್ನು ಬಿಟ್ಟು ಇನ್ನೇನನ್ನೋ ಧ್ಯಾನ ಮಾಡಿದರೆ ಏನೂ ಉಪಯೋಗವಿಲ್ಲ.\nನಮ್ಮ ಜ್ಯೋತಿಷಿಗಳು ಸಾಮಾನ್ಯವಾಗಿ 'ಇಂತಹ ಗ್ರಹಚಾರಕ್ಕೆ ಇಂತಹ ದೇವತೆಯನ್ನು ಉಪಾಸನೆ ಮಾಡು'\nಎಂದು ಹೇಳುತ್ತಾರೆ. ಅದರರ್ಥ ಭಗವಂತನನ್ನು ಆ ಪ್ರತೀಕದಲ್ಲಿ ಕಾಣು ಎಂದರ್ಥ. ಯಾವುದೇ ದೇವತೆಯನ್ನು\nಉಪಾಸನೆ ಮಾಡುವಾಗ ಆ ಪ್ರತೀಕದಲ್ಲಿ ಭಗವಂತನ ಉಪಾಸನೆ ಮಾಡದಿದ್ದರೆ ಅದು ನಿಜವಾದ\nಯೋಗ ವಾಗುವುದಿಲ್ಲ. ಧ್ಯಾನದಲ್ಲಿ ಕೇವಲ ಭಗವಂತನನ್ನು ಕಾಣಬೇಕು ಎನ್ನು ವ ಬಯಕೆ ಮತ್ತು ಎಲ್ಲಾ\nಪ್ರತೀಕದಲ್ಲೂ ಅವನನ್ನೇ ಕಾಣುವುದು ಶ್ರೇಷ್ಠವಾದ ಯೋಗ. ಈ ರೀತಿ ಬದುಕಿದಾಗ ನಮ್ಮ ಬದುಕೇ ಒಂದು\nಯೋಗವಾಗುತ್ತದೆ.\n\nಇತಿ ಷಷ್ಠೋ$5ಧ್ಯಾಯಃ\nಆರನೆಯ ಅಧ್ಯಾಯ ಮುಗಿಯಿತು\n\nಇಲ್ಲಿಗೆ ಭಗವದ್ಗೀತೆಯ ಮೊದಲ ಷಟ್ಕ(ಮೊದಲ ಆರು ಅಧ್ಯಾಯ) ಮುಗಿಯಿತು. ಈ ಷಟ್ಕದಲ್ಲಿ ಭಗವಂತನ\nಉಪಾಸನೆಯ ಜ್ಞಾನ ಮತ್ತು ಸಾಂಖ್ಯವನ್ನು ಕೃಷ್ಣ ವಿವರಿಸಿದ. ಜ್ಞಾನಪೂರ್ವಕವಾಗಿ ಭಗವದುಪಾಸನೆಯನ್ನು\nಮಾಡುವಂತಹ ವಿಧಾನವನ್ನು ಗೀತೆಯ ಮೊದಲ ಷಟ್ಕ ವಿವರಿಸುತ್ತದೆ. ಮುಂದೆ ಭಗವಂತನನ್ನು ಉಪಾಸನೆ\nಮಾಡುವ ವಿಷಯಾಂಶ(subject) ಮತ್ತು ಭಗವಂತನ ಮಹಿಮೆ-ಅದರ ವಿವರಗಳು ಬರುತ್ತವೆ.\n\nಅಧ್ಯಾಯ ಏಳು\n\nಹಿಂದಿನ ಆರು ಅಧ್ಯಾಯ(ಮೊದಲ ಷಟ್ಕ)ದಲ್ಲಿ ಕೃಷ್ಣ ಸಾಧಕನಾದವನು ಯಾವ ರೀತಿ ಸಾಧನೆಗೆ ತೊಡಗಬೇಕು,\nಕರ್ಮ ಹೇಗಿರಬೇಕು, ಧ್ಯಾನ ಹೇಗಿರಬೇಕು, ಇತ್ಯಾದಿ ಭಗವಂತನನ್ನು ತಿಳಿಯುವ ಸಾಧನದ ಬಗ್ಗೆ ಹೇಳಿದ.\nಎರಡನೇ ಷಟ್ಕ(ಅ-೭ರಿಂದ ೧೨) ಸಾಧನೆಯ ಮೂಲಕ ನಾವು ತಿಳಿದುಕೊಳ್ಳಬೇಕಾದ ಭಗವಂತನ\nಸ್ವರೂಪವನ್ನು, ವಿಭೂತಿಯನ್ನು, ವೈಭವವನ್ನು, ಆತನ ಮಹಿಮೆಯನ್ನು ಹೇಳುವ ಸಾಧ್ಯಾ $*ಧ್ಯಾಯ.\n\nಈ ಅಧ್ಯಾಯದಲ್ಲಿ ನಾವು ನಮ್ಮ ಅರಿವಿನ ಪೂರ್ಣ ಸಾಮರ್ಥ್ಯದಷ್ಟು ಭಗವಂತನನ್ನು ಹೇಗೆ ತಿಳಿಯಬಹುದು\nಎನ್ನುವುದನ್ನು ಕೃಷ್ಣ ವಿವರಿಸುತ್ತಾನೆ. ಯಾವುದನ್ನು ತಿಳಿದರೆ ಎಲ್ಲವನ್ನೂ ತಿಳಿದಂತಾಗುತ್ತದೋ ಅಂತಹ\nವಿಜ್ಞಾನವನ್ನು ಇಲ್ಲಿ ಕಾಣಬಹುದು. ಅಷ್ಟರೂಪದ ಅಕ್ಷರಪ್ರಕೃತಿಯ ಸೃಷ್ಟಿ; ನಾದಸೃಷ್ಟಿ; ಸೃಷ್ಟಿ ಕ್ರಿಯೆಯಲ್ಲಿ\nಚೇತನಪ್ರಕೃತಿ, ಶ್ರೀತತ್ವ ಮತ್ತು ಅದರ ಮಹತ್ವವನ್ನು ಕೃಷ್ಣ ಇಲ್ಲಿ ವಿವರಿಸಿದ್ದಾನೆ. ನೀರು, ಸೂರ್ಯ, ಚಂದ್ರ,\nಆಕಾಶ, ಭೂಮಿ, ಅಗ್ನಿ ಸ; ಆತ್ಮಬಲ, ವಾಯು, ತಪಸ್ಸು ಎಲ್ಲವುದರಲ್ಲೂ ಹೇಗೆ ಭಗವಂತನ ವಿಭೂತಿ ಅಡಗಿದೆ\nಎನ್ನುವುದರ ಸಂಕ್ಷಿಪ್ತ ಚಿತ್ರಣವನ್ನು ಕ್ರೋಡೀಕರಿಸಿ ಇಲ್ಲಿ ವಿವರಿಸಲಾಗಿದೆ.[ಭಗವಂತನ ವಿಭೂತಿಯನ್ನು\nವಿಶೇಷವಾಗಿ ಅಧ್ಯಾಯ ಹತ್ತರಲ್ಲಿ ಕಾಣಬಹುದು]. ತ್ರಿಗುಣಾತ್ಮಕವಾದ ಪ್ರಪಂಚದಲ್ಲಿನ ನಮ್ಮ ಬದುಕು;\nಮಾಯಾ ಪ್ರಪಂಚ ಮತ್ತು ಅದರಿಂದ ಹೊರ ಬರುವ ದಾರಿಯನ್ನು ಕೃಷ್ಣ ಇಲ್ಲಿ ವಿವರಿಸುತ್ತಾನೆ. ದುಷ್ಕೃತಿಗಳ\nಮತ್ತು ಪುಣ್ಯವಂತ ಸಜ್ಜನರ ವಿಧ; ಅವರಲ್ಲಿ ಮತ್ತು ಅವರ ಭಕ್ತಿಯಲ್ಲಿ ಶ್ರೇಷ್ಠ ಯಾವುದು; ಜ್ಞಾನ ಮತ್ತು ಭಕ್ತಿಯಿಂದ\nಯಾರು ಮುಕ್ತಿಯನ್ನು ಪಡೆಯುತ್ತಾರೆ-ಇತ್ಯಾದಿ ಅಧ್ಯಾತ್ಮ ವಿಜ್ಞಾನವನ್ನು ಈ ಅಧ್ಯಾಯ ವಿವರಿಸುತ್ತದೆ. ಈ\nಅಧ್ಯಾಯ ಭಗವಂತನ ಅಮೃತ ನುಡಿಯಿಂದ ಪ್ರಾರಂಭವಾಗುತ್ತದೆ.\n\nಭಗವಾನುವಾಚ ।\nಮಯ್ಯಾಸಕ್ತಮನಾಃ ಪಾರ್ಥ ಯೋಗಂ ಯುಂಜನ್‌ ಮದಾಶ್ರಯಃ |\nಅಸಂಶಯಂ ಸಮಗ್ರಂ ಮಾಂ ಯಥಾ ಜ್ಞಾಸ್ಯಸಿ ತಚ್ಛ ಣು ॥೧॥\n\nಭಗವಾನ್‌ ಉವಾಚ-ಭಗವಂತ ಹೇಳಿದನು:\n\nಮಯಿ ಆಸಕ್ತ ಮನಾಃ ಪಾರ್ಥ ಯೋಗಮ್‌ ಯುಂಜನ್‌ ಮತ್‌ ಆಶ್ರಯಃ |\n\nಅಸಂಶಯಮ್‌ ಸಮಗ್ರಮ್‌ ಮಾಮ್‌ ಯಥಾ ಜ್ಞಾಸ್ಯಸಿ ತತ್‌ ಶೃಣು -ಪಾರ್ಥಾ, ನನ್ನನ್ನೇ ಬಗೆ ತುಂಬಿ\nಪ್ರೀತಿಸುತ್ತಾ, ನನ್ನನ್ನೇ ಮೊರೆಹೊಕ್ಕು, ಯೋಗ ಸಾಧನೆಯಲ್ಲಿ ತೊಡಗುತ್ತಾ, ಖಚಿತವಾಗಿ ಅರಿವಿನ ತೆಕ್ಕೆ ತುಂಬಾ\nನನ್ನನ್ನು ಹೇಗೆ ಅರಿಯಬಲ್ಲೆ ಅದನ್ನು ಕೇಳು.\n\nಮದ್ದಾನೆ ಅಥವಾ ಗೂಳಿಯಂತಹ ನಮ್ಮ ಮನಸ್ಸನ್ನು ಮಣಿಸಿ, ಸಾಧನೆಯ ಹಾದಿಯಲ್ಲಿ ಅದನ್ನು ಪಕ್ವಗೊಳಿಸಿದ\nಮೇಲೆ, ಭಗವಂತನಲ್ಲಿ ಮತ್ತೆಂದೂ ಕದಲದ, ಸುದೃಡ ಮತ್ತು ಗಾಢವಾದ ಭಕ್ತಿಯಿಂದ, ಅಹಂಕಾರ ತೊರೆದು,\n\nಸಂಪೂರ್ಣ ಶರಣಾಗತಿಯಿಂದ (ಎಲ್ಲಾ ಕಾಲದಲ್ಲೂ ನಾವು ಭಗವಂತನ ಅಧೀನ ಎನ್ನುವ ಎಚ್ಚರದಿಂದ),\nಭಗವಂತನಲ್ಲಿ ಸಂಪೂರ್ಣವಾಗಿ ತನ್ನನ್ನು ತಾನು ಅರ್ಪಿಸಿಕೊಂಡು, ಧ್ಯಾನಯೋಗದಲ್ಲಿ ತೊಡಗಿದ ಮೇಲೆ,\n\"ಅರಿವಿನ ಪೂರ್ಣ ಸಾಮರ್ಥ್ಯದಷ್ಟು ಭಗವಂತನನ್ನು ಹೇಗೆ ತಿಳಿಯಬಹುದು' ಅದನ್ನು ಕೇಳು ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.\n\nಜ್ಞಾನಂ ತೇ$*ಹಂ ಸವಿಜ್ಞಾನಮಿದಂ ವಕ್ಷ್ಯಾಮ್ಯಶೇಷತಃ\nಯಜ್‌ ಜ್ಞಾತ್ವಾ ನೇಹ ಭೂಯೋಕನ್ಯಜ್‌ ಜ್ಞಾತವ್ಯಮವಶಿಷ್ಯತೇ ॥೨॥\n\nಜ್ಞಾನಮ್‌ ತೇ ಅಹಮ್‌ ಸ ವಿಜ್ಞಾನಮ್‌ ಇದಮ್‌ ವಕ್ಷ್ಯಾಮಿ ಅಶೇಷತಃ |\n\nಯತ್‌ ಜ್ಞಾತ್ವಾ ನ ಇಹ ಭೂಯಃ ಅನ್ಯತ್‌ ಜ್ಞಾತವ್ಯಮ್‌ ಅವಶಿಷ್ಯತೇ -ತಿಳಿಯಬೇಕಾದ ನನ್ನ ಹಿರಿಮೆಯನ್ನು\nಅದರ ಬಿತ್ತರದ ಜತೆಗೆ ನಿನಗೆ ನಾನು ಪೂರ್ತಿಯಾಗಿ ಹೇಳುತ್ತೇನೆ. ಇದನ್ನು ತಿಳಿದರೆ ಮತ್ತೆ ಈ ವಿಷಯದಲ್ಲಿ\nಬೇರೆ ತಿಳಿಯುವಂತದ್ದೇನೂ ಉಳಿದಿರುವುದಿಲ್ಲ.\n\nಯಾವುದನ್ನು ತಿಳಿದರೆ ಎಲ್ಲವನ",
  "7.1": "ಭಗವಾನ್‌ ಉವಾಚ-ಭಗವಂತ ಹೇಳಿದನು:\n\nಮಯಿ ಆಸಕ್ತ ಮನಾಃ ಪಾರ್ಥ ಯೋಗಮ್‌ ಯುಂಜನ್‌ ಮತ್‌ ಆಶ್ರಯಃ |\n\nಅಸಂಶಯಮ್‌ ಸಮಗ್ರಮ್‌ ಮಾಮ್‌ ಯಥಾ ಜ್ಞಾಸ್ಯಸಿ ತತ್‌ ಶೃಣು -ಪಾರ್ಥಾ, ನನ್ನನ್ನೇ ಬಗೆ ತುಂಬಿ\nಪ್ರೀತಿಸುತ್ತಾ, ನನ್ನನ್ನೇ ಮೊರೆಹೊಕ್ಕು, ಯೋಗ ಸಾಧನೆಯಲ್ಲಿ ತೊಡಗುತ್ತಾ, ಖಚಿತವಾಗಿ ಅರಿವಿನ ತೆಕ್ಕೆ ತುಂಬಾ\nನನ್ನನ್ನು ಹೇಗೆ ಅರಿಯಬಲ್ಲೆ ಅದನ್ನು ಕೇಳು.\n\nಮದ್ದಾನೆ ಅಥವಾ ಗೂಳಿಯಂತಹ ನಮ್ಮ ಮನಸ್ಸನ್ನು ಮಣಿಸಿ, ಸಾಧನೆಯ ಹಾದಿಯಲ್ಲಿ ಅದನ್ನು ಪಕ್ವಗೊಳಿಸಿದ\nಮೇಲೆ, ಭಗವಂತನಲ್ಲಿ ಮತ್ತೆಂದೂ ಕದಲದ, ಸುದೃಡ ಮತ್ತು ಗಾಢವಾದ ಭಕ್ತಿಯಿಂದ, ಅಹಂಕಾರ ತೊರೆದು,\n\nಸಂಪೂರ್ಣ ಶರಣಾಗತಿಯಿಂದ (ಎಲ್ಲಾ ಕಾಲದಲ್ಲೂ ನಾವು ಭಗವಂತನ ಅಧೀನ ಎನ್ನುವ ಎಚ್ಚರದಿಂದ),\nಭಗವಂತನಲ್ಲಿ ಸಂಪೂರ್ಣವಾಗಿ ತನ್ನನ್ನು ತಾನು ಅರ್ಪಿಸಿಕೊಂಡು, ಧ್ಯಾನಯೋಗದಲ್ಲಿ ತೊಡಗಿದ ಮೇಲೆ,\n\"ಅರಿವಿನ ಪೂರ್ಣ ಸಾಮರ್ಥ್ಯದಷ್ಟು ಭಗವಂತನನ್ನು ಹೇಗೆ ತಿಳಿಯಬಹುದು' ಅದನ್ನು ಕೇಳು ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.",
  "7.2": "ಜ್ಞಾನಮ್‌ ತೇ ಅಹಮ್‌ ಸ ವಿಜ್ಞಾನಮ್‌ ಇದಮ್‌ ವಕ್ಷ್ಯಾಮಿ ಅಶೇಷತಃ |\n\nಯತ್‌ ಜ್ಞಾತ್ವಾ ನ ಇಹ ಭೂಯಃ ಅನ್ಯತ್‌ ಜ್ಞಾತವ್ಯಮ್‌ ಅವಶಿಷ್ಯತೇ -ತಿಳಿಯಬೇಕಾದ ನನ್ನ ಹಿರಿಮೆಯನ್ನು\nಅದರ ಬಿತ್ತರದ ಜತೆಗೆ ನಿನಗೆ ನಾನು ಪೂರ್ತಿಯಾಗಿ ಹೇಳುತ್ತೇನೆ. ಇದನ್ನು ತಿಳಿದರೆ ಮತ್ತೆ ಈ ವಿಷಯದಲ್ಲಿ\nಬೇರೆ ತಿಳಿಯುವಂತದ್ದೇನೂ ಉಳಿದಿರುವುದಿಲ್ಲ.\n\nಯಾವುದನ್ನು ತಿಳಿದರೆ ಎಲ್ಲವನ್ನೂ ತಿಳಿದಂತಾಗುತ್ತದೋ ಅದನ್ನು ನಿನಗೆ ಹೇಳುತ್ತೇನೆ ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.\nಉಪನಿಷತ್ತಿನಲ್ಲಿ ಒಂದು ಮಾತಿದೆ “ಯಸ್ಮಿನ್‌ ವಿಜ್ಞಾತೇ ಸರ್ವಮಿದಂ ವಿಜ್ಞಾತಂಭವತಿ” |॥|ಶಾಂಡಿಲ್ಯ-೨.೨;\nಮುಂಡಕ ೧.೧.೩॥ ಅಂದರೆ ಯಾವುದನ್ನು ತಿಳಿದರೆ ಎಲ್ಲವೂ ತಿಳಿಯುತ್ತದೋ ಅದನ್ನು ಮೊದಲು ತಿಳಿಯಬೇಕು.\nನಾವು ಭಗವಂತನನ್ನು ತಿಳಿದರೆ ಈ ಪ್ರಪಂಚವನ್ನು ತಿಳಿದಂತೆ. ಅದನ್ನು ಬಿಟ್ಟು ಪ್ರಪಂಚವನ್ನು ತಿಳಿದು\nಭಗವಂತನನ್ನು ತಿಳಿಯಬೇಕು ಅಂದುಕೊಂಡರೆ ಅದು ಅಸಾಧ್ಯ. ಇಲ್ಲಿ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಯಾವ\nಸಂಗತಿಯನ್ನು ತಿಳಿದರೆ ಮತ್ತೆ ಬೇರೆ ತಿಳಿದುಕೊಳ್ಳಬೇಕಾದ ಸಂಗತಿ ಉಳಿಯುವುದಿಲ್ಲವೋ ಅಂತಹ\nವಿಜ್ಞಾನವನ್ನು ನಿನಗೆ ಕೊಡುತ್ತೇನೆ” ಎಂದು. ಜ್ಞಾನ ವಿಜ್ಞಾನವಾದಾಗಲೇ ಅದು ಸಮಗ್ರವಾಗುವುದು. ವಿಜ್ಞಾನ\nಅಂದರೆ ವಿ*ಜ್ಞಾನ. ಇಲ್ಲಿ 'ವಿ' ಉಪಸರ್ಗ, \"ವಿ'- ವಿಲಕ್ಷಣವಾದ, ವಿಶಿಷ್ಟ ವಾದ, ವಿಶೇಷವಾದ, ಇತ್ಯಾದಿ ಅರ್ಥವನ್ನು\nಕೊಡುತ್ತದೆ. ಒಂದು ವಿಷಯವನ್ನು ತಳಸ್ಪರ್ಶಿಯಾಗಿ ತಿಳಿಯುವುದು ವಿಜ್ಞಾನ. ಇಲ್ಲಿ ಕೃಷ್ಣ ಹೇಳುತ್ತಿರುವುದು\nವಿಜ್ಞಾನದ ಬಗ್ಗೆ. 'ದೇವರು ಇದ್ದಾನೆ, ಅವನು ಸರ್ವಸಮರ್ಥ, ಸರ್ವಾಂತರ್ಯಾಮಿ' ಎನ್ನುವುದು ಜ್ಞಾನ; ಆತ\nಎಲ್ಜೆಲ್ಲಿ ಹೇಗಿದ್ದಾನೆ, ಯಾವ ವಸ್ತುವಿನಲ್ಲಿ ಯಾವ ವಿಭೂತಿಯಾಗಿದ್ದಾನೆ ಎಂದು ವಿವರವಾಗಿ ತಿಳಿಯುವುದು\nವಿಜ್ಞಾನ.\n",
  "7.3": "ಮನುಷ್ಯಾಣಾಮ್‌ ಸಹಸ್ರೇಷು ಕಶ್ಚಿತ್‌ ಯತತಿ ಸಿದ್ಧಯೇ ।\n\nಯತತಾಮ್‌ ಅಪಿ ಸಿದ್ಧಾನಾಮ್‌ ಕಶ್ಚಿತ್‌ ಮಾಮ್‌ ವೇತ್ತಿ ತತ್ತ್ವತಃ -ಸಾವಿರಾರು ಮಂದಿಯಲ್ಲಿ ಯಾರೋ ಒಬ್ಬ\nಸಿದ್ಧಿಗಾಗಿ ಪ್ರಯತ್ನಿಸುತ್ತಾನೆ. ಪ್ರಯತ್ನಿಸಿದವರಲ್ಲಿ, ಪ್ರಯತ್ನಿಸಿ ಗುರಿಮುಟ್ಟಿದವರಲ್ಲಿ, ಯಾರೋ ಒಬ್ಬ ನನ್ನನ್ನು\nಸರಿಯಾಗಿ ಅರಿತುಕೊಳ್ಳುತ್ತಾನೆ.\nಭಗವಂತನನ್ನು ಯಾರು ತಳಸ್ಪರ್ಶಿಯಾಗಿ ತಿಳಿಯಲು ಸಾಧ್ಯ? ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಸಾವಿರಾರು ಮಾನವರಲ್ಲಿ\nಕೆಲವರು ಸಿದ್ಧಿಗಾಗಿ ಪ್ರಯತ್ನಿಸುತ್ತಾರೆ. ಈ ರೀತಿ ಯೋಗದಲ್ಲಿ ತೊಡಗಿಸಿಕೊಂಡು ಅದರಲ್ಲಿ ಗುರಿಮುಟ್ಟಿದ\nಅನೇಕರಲ್ಲಿ, “ಒಬ್ಬನು ನನ್ನನ್ನು ನಿಜವಾಗಿ ಅರ್ಥ ಮಾಡಿಕೊಂಡಿದ್ದಾನೆ' ಎಂದು ಹೇಳುವುದೂ ಕಷ್ಟ”. ಅಪರೋಕ್ಷ\nಜ್ಞಾನದಲ್ಲಿ ಎತ್ತರಕ್ಕೇರಿದ ಸಿದ್ಧಪುರುಷರಲ್ಲೂ ಕೂಡಾ ಭಗವಂತನನ್ನು ತತ್ತ್ವತಃ ತಿಳಿದುಕೊಳ್ಳುವವರು ಬಹಳ\nವಿರಳ.\n",
  "7.4": "ಭೂಮಿಃ ಆಪಃ ಅನಲಃ ವಾಯುಃ ಖಮ್‌ ಮನಃ ಬುದ್ಧಿಃ ಏವ ಚ।\nಅಹಂಕಾರಃ ಇತಿ ಇಯಮ್‌ ಮೇ ಭಿನ್ನಾ ಪ್ರಕೃತಿ ಅಷ್ಟ ಧಾ- ಮಣ್ಣು, ನೀರು, ಬೆಂಕಿ, ಗಾಳಿ, ಆಕಾಶ, ಮನಸ್ಸು ಸ;\nಬುದ್ಧಿ,[ಸುಪ್ತಪ್ರಜ್ಞೆಯಿಂದ ಕೂಡಿದ] ಅಹಂಕಾರ ಹೀಗೆ ನನ್ನ ಅಧೀನವಾದ ಈ ಜಡ ಪ್ರಕೃತಿ ಎಂಟು ಬಗೆಯಾಗಿದೆ.\n\nಈ ಶ್ಲೋಕ ಭಗವಂತನ ಪ್ರಪಂಚ ಸೃಷ್ಟಿಯ ವಿರಾಟ ರೂಪವನ್ನು ಸಮಷ್ಟಿಯಾಗಿ ತಿಳಿಸುತ್ತದೆ. ನಮಗೆ ತಿಳಿದಂತೆ\nಸೃಷ್ಟಿ ಪೂರ್ವದಲ್ಲಿ ಈ ಸಂಪೂರ್ಣ ಜಗತ್ತು ಸೂಕ್ಷ್ಮ ರೂಪದಲ್ಲಿ ಆ ಭಗವಂತನ ಉದರದಲ್ಲಿ ನೆಲೆಗೊಂಡಿದ್ದು,\nನಂತರ ಭಗವಂತ ಈ ಸೃಷ್ಟಿಯನ್ನು ನಿರ್ಮಿಸಿದ. ಹೀಗೆ ಮೊದಲು ನಿರ್ಮಾಣವಾದುದು ಈ ಜಡಪ್ರಕೃತಿ. ಇಲ್ಲಿ\nಪಂಚಭೂತಗಳು(ಮಣ್ಣು, ನೀರು, ಬೆಂಕಿ, ಗಾಳಿ, ಆಕಾಶ) ಜೊತೆಗೆ ಮನಸ್ಸು, ಬುದ್ಧಿ ಮತ್ತು ಅಹಂಕಾರ. ಇವು\nಒಟ್ಟಿಗೆ ಎಂಟು ಬಗೆ. ಈ ಇಡೀ ಸ್ಥೂಲಪ್ರಪಂಚ ಮಣ್ಣು ನೀರು ಬೆಂಕಿ ಗಾಳಿ ಆಕಾಶ ಇದರ ವಿಕಾರ. ಆದ್ದರಿಂದ ಈ\nಪ್ರಪಂಚದಲ್ಲಿರುವ ಸಮಸ್ತ ಜಡಪದಾರ್ಥಗಳ ಮೂಲದ್ರವ್ಯ ಪಂಚಭೂತಗಳು.\n\nಇಲ್ಲಿ ನಮಗೆ ಒಂದು ಪ್ರಶ್ನೆ ಕಾಡಬಹುದು. ಅದೇನೆಂದರೆ ಪಂಚಭೂತಗಳ ಸೃಷ್ಟಿಯಲ್ಲಿ ಆಕಾಶದ ಸೃಷ್ಟಿ\nಅಂದರೇನು? ಎಂದು. ಮೂಲತಃ ಆಕಾಶದ ಸೃಷ್ಟಿ ವಾಸ್ತವ ಅಲ್ಲ ಇದು ಸಾಪೇಕ್ಷವಾಗಿ . ಅಂತರಿಕ್ಷ (Space)\nಮೊದಲೇ ಇತ್ತು. ಅದರಲ್ಲಿ ಭಗವಂತ ತನ್ನ ರೂಪವನ್ನು ಆವಿರ್ಭಾವ ಗೊಳಿಸುವುದೇ ಆಕಾಶ ಸೃಷ್ಟಿ . ಬಣ್ಣವಿಲ್ಲದ\nಅಂತರಿಕ್ಷದಲ್ಲಿ “ಕಣ್ಣಿಗೆ ಕಾಣದ ನೀಲ ವರ್ಣದ(Ultraviolet) ಆಕಾಶ ಸೃಷ್ಟಿ ಯಾಯಿತು.(ಇದನ್ನು ಹದಿಮೂರನೇ\nಶತಮಾನದಲ್ಲಿ ಮಧ್ವಾಚಾರ್ಯರು ಉಲ್ಲೇಖಿಸಿದ್ದಾರೆ) ಅಲ್ಲಿ ಕಂಪನ ಉಂಟಾಗಿ ಅದರಿಂದ ಗಾಳಿ ಹುಟ್ಟಿತು.\nಗಾಳಿಯ ಕಂಪನದಿಂದ ಬೆಂಕಿ ಹಾಗೂ ಬೆಂಕಿಯಿಂದ ನೀರಿನ ಸೃಷ್ಟಿಯಾಯಿತು. ಈ ನೀರು ಗಟ್ಟಿಯಾಗಿ ಕಾಲ\nಕ್ರಮೇಣ ಭೂಮಿಯಾಗಿ ವಿಕಸನಗೊಂಡಿತು. ಹೀಗೆ ಈ ಪಂಚಭೂತಗಳಿಂದ ಅನಂತ ವಸ್ತುಗಳ\nನಿರ್ಮಾಣವಾಯಿತು.\n\nಮೊದಲು ಪಂಚಭೂತಗಳಿಂದ ಅನ್ನಮಯಕೋಶದ ಸೃಷ್ಟಿ; ನಂತರ ಬೆಂಕಿ, ಗಾಳಿ ಆಕಾಶದಿಂದ\nಪ್ರಾಣಮಯಕೋಶದ ಸೃಷ್ಟಿ; ಈ ಪ್ರಾಣಮಯಕೋಶದ ಒಳಗೆ ಮನಸ್ಸು ಮತ್ತು ಬುದ್ಧಿಯಿಂದಾದ\n\nಮನೋಮಯಕೋಶದ ಸೃಷ್ಟಿ; ನಂತರ ನಮ್ಮ ನೆನಪಿನ ಶಕ್ತಿಯ ಅಹಂಕಾರತತ್ವ (awareness of self ಚಿತ್ತ,\nಚೇತನ)ದಿಂದಾದ ವಿಜ್ಞಾನಮಯಕೋಶ ಸೃಷ್ಟಿಯಾಯಿತು. ಇಲ್ಲಿ ಮನಸ್ಸು ಸೃಷ್ಟಿಯಾಯಿತು ಎಂದರೆ ಮನಸ್ಸಿನ\nಅಭಿಮಾನಿ ದೇವತೆಯ ಸೃಷ್ಟಿಯಾಯಿತು ಎಂದರ್ಥ; ಭೂಮಿ ಸೃಷ್ಟಿಯಾಯಿತು ಎಂದರೆ ಈ ಜಡವಾದ\nಭೂಮಿಯ ಜೊತೆಗೆ ಭೂಮಿಯ ಅಭಿಮಾನಿ ದೇವತೆಯ ಸೃಷ್ಟಿಯಾಯಿತು ಎಂದರ್ಥ. ಅದೇ ರೀತಿ ವಾಯುವಿನ\nಸೃಷ್ಟಿ ಎಂದಾಗ ಅಲ್ಲಿ ವಾಯುವಿನ ಜೊತೆಗೆ ನಲವತ್ತೊಂಬತ್ತು ದೇವತೆಗಳ ಸೃಷ್ಟಿಯಾಯಿತು ಎಂದರ್ಥ. ನಮಗೆ\nತಿಳಿದಂತೆ ಭೂಮಿಯನ್ನು ಆವರಿಸಿರುವ ವಾಯುವಿನ ಪದರು ನಲವತ್ತೊಂಬತ್ತು. ಭೂಮಿಯಿಂದ ವಿವಿಧ\nದೂರದಲ್ಲಿ ಗಾಳಿಯ ವಿವಿಧ ಒತ್ತಡಕ್ಕನುಗುಣವಾಗಿ ಈ ವಿಭಾಗ. ಇದನ್ನು ನಿಯಮಿತವಾಗಿ ಆಯಾ ಅಭಿಮಾನಿ\nದೇವತೆಗಳು ನಿರ್ವಹಿಸುತ್ತಾರೆ. (\"ಭಾರದ್ವಾಜ ಸಂಹಿತದಲ್ಲಿ ಈ ಬಗ್ಗೆ ಮತ್ತು ವಿಮಾನ ತಾಂತ್ರಿಕತೆ ಬಗ್ಗೆ\nಸಂಪೂರ್ಣ ವಿವರವನ್ನು ಕಾಣಬಹುದು). ಹೀಗೆ ಭಗವಂತನ ಅಧೀನವಾಗಿ ಅಷ್ಟರೂಪದ ಅಕ್ಷರಪ್ರಕೃತಿ\nರೂಪುಗೊಂಡಿತು. ಈ ಅಷ್ಟ ವಿಧದ ಪ್ರಪಂಚದಲ್ಲಿ ಅಷ್ಟಾಕ್ಷರ ವಾಚ್ಯನಾಗಿ ಭಗವಂತ ತುಂಬಿದ.\n\nನಾದಸೃಷ್ಟಿಯ ಮೊದಲ ಸೃಷ್ಟಿ ಓಂಕಾರ. ಓಂಕಾರದಲ್ಲಿ ಎಂಟು ಅಕ್ಷರಗಳಿವೆ. ನಾಭಿಯಿಂದ ಹೊರಟು ಉಚ್ಚಾರದ\nಕೊನೆಯ ತನಕ ಒಟ್ಟು ಎಂಟು ಅಕ್ಷರಗಳು. ಅವುಗಳೆಂದರೆ: ಅಕಾರ , ಉಕಾರ, ಮಕಾರ, ನಾದ, ಬಿಂದು, ಕಲೆ,\nಶಾಂತ, ಅತಿಶಾಂತ. ಹೀಗೆ ಎಂಟು ಅಕ್ಷರದಿಂದ ವಾಚ್ಯನಾಗಿ; ವಿಶ್ವ, ತೈಜಸ, ಪ್ರಾಜ್ಞ, ತುರೀಯ , ಆತ್ಮ,\nಅಂತರಾತ್ಮ, ಪರಮಾತ್ಮ ಮತ್ತು ಜ್ಞಾನಾತ್ಮ ಎನ್ನುವ ಎಂಟು ರೂಪದಲ್ಲಿ ಭಗವಂತ ಈ ಅಷ್ಟವಿಧ ಪ್ರಕೃತಿಯಲ್ಲಿ\nತುಂಬಿದ. ಹೀಗೆ ಇಡೀ ಪ್ರಪಂಚ ಅಷ್ಟ ವಿಧದಲ್ಲಿ ವಿಕಾರಗೊಂಡಿತು.\n\n(ಅಧ್ಯಾತ್ಮದಲ್ಲಿ ಪ್ರತಿಯೊಂದು ಸಂಖ್ಯೆಯ ಹಿಂದೆ ಒಂದು ವೇದಾಂತವಿದೆ. ಸೃಷ್ಟಿ ಪ್ರಕ್ರಿಯೆಯಲ್ಲಿ ಎಂಟರ\nಮಹತ್ವವನ್ನು ಇಲ್ಲಿ ನೋಡಿದೆವು. ಬನ್ನಂಜೆಯವರ “ಅಂಕೆಯಲ್ಲಿ ಅಧ್ಯಾತ್ಮ' ಎನ್ನುವ ಪುಟ್ಟ\nಮೇಲೆ ಬೆಳಕು ಚೆಲ್ಲುತ್ತದೆ).\n",
  "7.5": "ಅಪರಾ ಇಯಮ್‌ ಇತಃ ತು ಅನ್ಯಾಮ್‌ ಪ್ರಕೃತಿಮ್‌ ವಿದ್ಧಿ ಮೇ ಪರಾಮ್‌ |\n\nಜೀವಭೂತಾಮ್‌ ಮಹಾಬಾಹೋ ಯಯಾ ಇದಮ್‌ ಧಾರ್ಯತೇ ಜಗತ್‌- ಎರಡು ಪ್ರಕೃತಿಗಳಲ್ಲಿ ಇದು\nಕೆಳಮಟ್ಟದ್ದು. ನನ್ನ ಅಧೀನವಾದ ಇನ್ನೊಂದು ಪ್ರಕೃತಿ ಇದಕ್ಕಿಂತ ಮಿಗಿಲಾದದ್ದು. ಅದೇ ಚೇತನ ಪ್ರಕೃತಿ;\nಶ್ರೀತತ್ವ. ಎಲ್ಲಾ ಜೀವರಿಗೆ ಆಸರೆಯಾಗಿ ಎಂದೆಂದೂ ಇರುವಂತಾದ್ದು. ಮಹಾವೀರಾ, ಅದು ಈ ಜಗವನ್ನು\nಹೊತ್ತುಕೊಂಡಿದೆ.\n\nಅಚೇತನ ಸೃಷ್ಟಿ ಗೆ ಒಬ್ಬ ನಿಮಿತ್ತ ಕಾರಣ ಮತ್ತು ಒಂದು ಉಪಧಾನ ಕಾರಣ. ಜಡಪ್ರಕೃತಿ ಪ್ರಪಂಚಕ್ಕೆ ಉಪಧಾನ\nಕಾರಣ ಹಾಗೂ ಅದರ ಮೂಲಕ ಭಗವಂತ ಸಮಸ್ತ ಸೃಷ್ಟಿ ಗೆ ನಿಮಿತ್ತ ಕಾರಣ. ಚೇತನದಲ್ಲಿ ಎರಡು ವಿಧ. ಚರ\nಮತ್ತು ಅಚರ. ಅಚರವಾದ ಚೇತನ(ಉದಾ-ಮರ ಗಿಡಗಳು)ದ ಸೃಷ್ಟಿಗೆ ಮೇಲೆ ಹೇಳಿದಂತೆ ಒಬ್ಬ ನಿಮಿತ್ತ ಕಾರಣ\n\nಮತ್ತು ಒಂದು ಉಪಧಾನ ಕಾರಣ ಸಾಕು. ಆದರೆ ಚೇತನದಲ್ಲಿ ಚರವಾದ ಚೇತನ(ಅಂಡಜ ಮತ್ತು ಜರಾಯು)\nಸೃಷ್ಟಿಗೆ ಒಂದು ನಿಮಿತ್ತ ಕಾರಣ ಸಾಲದು. ಇಲ್ಲಿ ಎರಡು ನಿಮಿತ್ತ ಕಾರಣ ಬೇಕು. ಒಂದು ತಂದೆ, ಒಂದು ತಾಯಿ.\nಎರಡು ಚೇತನದಿಂದ ಒಂದು ಚೇತನ ಸೃಷ್ಟಿ. ಇದರ ಪ್ರಾರಂಭ ಮೂಲ ಸೃಷ್ಟಿಯಲ್ಲಿಯೇ ಆಗಿದೆ. ಹೀಗೆ ಎರಡು\nಚೇತನ ಹಾಗೂ ಒಂದು ಜಡ ಸೇರಿ ಈ ಸಮಸ್ತ ಸೃಷ್ಟಿಯಾಗಿರುವುದು. ಹಿಂದೆ ಹೇಳಿದಂತೆ ವಸ್ತುತಃ\nಪ್ರಳಯಕಾಲದಲ್ಲಿ ಇಡೀ ಪ್ರಪಂಚ ಭಗವಂತನ ಉದರದಲ್ಲೇ ಇದ್ದದ್ದು. ಆದ್ದರಿಂದ ಅವನೇ ತಂದೆ, ಅವನೇ\nತಾಯಿ. ಆದರೂ ಈ ಪ್ರಪಂಚದಲ್ಲಿರುವ ಜೀವ ಜಾತದ ಸೃಷ್ಟಿಗೆ ಮುಂದೆ ಹೇಗೆ ತಂದೆ ತಾಯಿ ಎನ್ನುವ ಎರಡು\nಚೇತನ ಬೇಕೋ ಅದನ್ನು ಸೃಷ್ಟಿಯ ಆದಿಯಲ್ಲೇ ಭಗವಂತ ಮಾಡಿದ. ಪ್ರಪಂಚದಲ್ಲಿ ಯಾವ ರೀತಿ ಜೀವದ ಸೃಷ್ಟಿ\nಪ್ರಕ್ರಿಯೆ ಮುಂದುವರಿಯುತ್ತದೋ ಅದೇ ರೀತಿ ಪ್ರಾರಂಭದಿಂದ ಆ ವ್ಯವಸ್ಥೆ ಮಾಡಿದ ಭಗವಂತ. ಅದರದ್ದೇ\nಮುಂದುವರಿಕೆ ಈ ಸೃಷ್ಟಿ.\n\nಈ ಶ್ಲೋಕದಲ್ಲಿ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ನಾನು ಹಿಂದೆ ಹೇಳಿದ ಪ್ರಕೃತಿ “ಜಡಪ್ರಕೃತಿ' ; ಆದರೆ ಅದಕ್ಕಿಂತ ಬಿನ್ನವಾದ\nಮತ್ತು ಶ್ರೇಷ್ಠವಾದ ಇನ್ನೊಂದು ಪ್ರಕೃತಿ ಇದೆ” ಎಂದು. ಅದೇ ಇಡೀ ಪ್ರಪಂಚಕ್ಕೆ ಮಾತೃ ಸ್ಥಾನ ಕೊಟ್ಟಿರುವ ಚಿತ್‌\nಪ್ರಕೃತಿ. ವೇದದಲ್ಲಿ ಹೇಳುವಂತೆ ಜಡಪ್ರಕೃತಿ 'ಅಕ್ಷರ', ಅದಕ್ಕಿಂತ ಭಿನ್ನವಾದ ಚೇತನಪ್ರಕೃತಿ-'ಪರಮಾಕ್ಷರ'.\nಭಗವಂತ “ಪರತ-ಪರಮಾಕ್ಷರ'. ಹೀಗೆ ಭಗವಂತನಿಗೂ ಮತ್ತು ಪ್ರಪಂಚಕ್ಕೂ ಮಾಧ್ಯಮವಾಗಿ\nಶ್ರೀತತ್ವ(ಶ್ರೀಲಕ್ಷ್ಮಿ)ವಿದೆ. ಈ ಕಾರಣದಿಂದ ಲಕ್ಷ್ಮಿಯನ್ನು ಲೋಕಮಾತೆ ಎನ್ನುತ್ತಾರೆ. ಈ ಜಗತ್ತನ್ನು ಸೃಷ್ಟಿ\nಮಾಡುವಾಗ ಜಡ ಪ್ರಕೃತಿಯನ್ನು ಉಪಧಾನ ಕಾರಣವಾಗಿ ಬಳಸಿದರೆ, ಆ ಜಡವಾದ ಶರೀರ(ಪಿಂಡಾಂಡ)ದಲ್ಲಿ\nಜೀವದ ಸೃಷ್ಟಿಯಾಗಬೇಕಾದರೆ ಜೀವಭೂತಳಾದ ಚೇತನಾ ಶಕ್ತಿ ಹೊಂದಿರುವ ಚಿತ್‌ ಪ್ರಕೃತಿಯನ್ನು\nಕಾರಣವಾಗಿ ಬಳಸಿದ ಭಗವಂತ. ಹೀಗೆ ಜಗತ್ತಿನ ಮೊದಲ ಜೀವ ಚತುರ್ಮುಖನ ಸೃಷ್ಟಿ ಶ್ರೀತತ್ವದಿಂದಾಯಿತು.\nಹೀಗೆ ಜಗತ್ತಿನ ಮೂಲದಲ್ಲೇ ಪ್ರಕೃತಿ ಮತ್ತು ಪುರುಷ ಎನ್ನುವ ಎರಡು ವಿಧದ ಚೇತನವನ್ನು ನಾವು ಕಾಣುತ್ತೇವೆ.\nಜೀವ ಸ್ವರೂಪದಲ್ಲೂ ಗಂಡು ಮತ್ತು ಹೆಣ್ಣು ಎನ್ನುವ ಎರಡು ಪ್ರಭೇದವಿದೆ ಎನ್ನುವುದು ಸೃಷ್ಟಿಯ ಆದಿಯಿಂದಲೇ\nತಿಳಿಯುತ್ತದೆ. ಪುರುಷ ಮತ್ತು ಪ್ರಕೃತಿ ಎನ್ನುವ ಭಗವಂತನ ಎರಡು ಮುಖದಿಂದ ಈ ಸೃಷ್ಟಿಯಾಯಿತು. ಜಡಕ್ಕೆ\nಲಿಂಗ ಭೇದವಿಲ್ಲ. ಆದರೂ ನಾವು ಕೆಲವು ಜಡ ವಸ್ತುವನ್ನು ಹೆಣ್ಣಾಗಿ ಮತ್ತು ಗಂಡಾಗಿ ಗುರುತಿಸುತ್ತೇವೆ. ಇದು ಆ\nವಸ್ತುವಿನ ಅಭಿಮಾನಿ ದೇವತೆಯ ಲಿಂಗಕ್ಕನುಗುಣವಾಗಿ ಗುರುತಿಸಲ್ಪಟ್ಟಿರುವುದು. ಉದಾಹರಣೆಗೆ ನದಿ: ನದಿಯ\nಅಭಿಮಾನಿ ದೇವತೆಗಳಲ್ಲಿ ಹೆಚ್ಚಿನವರು ಸ್ತ್ರೀಲಿಂಗ; ಅದೇ ರೀತಿ ಭೂಮಿಯ ಅಭಿಮಾನಿ ದೇವತೆ ಕೂಡಾ ಹೆಣ್ಣು.\nಈ ಕಾರಣಕ್ಕಾಗಿ ನದಿಯನ್ನು ಸ; ಭೂಮಿಯನ್ನು ನಾವು ತಾಯಿ ರೂಪದಲ್ಲಿ ಕಾಣುತ್ತೇವೆ.\n\nಹೀಗೆ ಜಗತ್ತಿನ ಮೂಲ ಸಂಗತಿ ಭಗವಂತ(ಪುರುಷ) ಮತ್ತು ಆತನ ಅಧೀನವಾಗಿ ಜಡ ಪ್ರಕೃತಿ ಮತ್ತು ಚಿತ್‌\nಪ್ರಕೃತಿ. ಇವು ಸದಾ ನಿತ್ಯ -ಎಂದೂ ನಾಶವಿಲ್ಲದವು. ಆಕಾರದ(ವಿಕೃತಿಯ) ನಾಶವಾಗುತ್ತದೆ ಹೊರತು\nಮೂಲದ್ರವ್ಯ ಉತ್ಪತ್ತಿ ನಾಶ ಜಗತ್ತಿನಲ್ಲಿಲ್ಲ. ಆದ್ದರಿಂದ ಇವು ಕ್ಷರವಿಲ್ಲದ(ಅ-ಕ್ಷರ) ಸಂಗತಿಗಳು. ಈ ಮೂರರಿಂದ\n'ಕ್ಷರ' ವಾದ ಪ್ರಪಂಚ ಸೃಷ್ಟಿಯಾಗುತ್ತದೆ.\n",
  "7.6": "ಏತತ್‌ ಯೋನೀನಿ ಭೂತಾನಿ ಸರ್ವಾಣಿ ಇತಿ ಉಪಧಾರಯ |\nಅಹಮ್‌ ಕೃತ್ಸಸ್ಯ ಜಗತಃ ಪ್ರಭವಃ ಪ್ರಳಯಃ ತಥಾ-ಈ ಎರಡು ಪ್ರಕೃತಿಗಳಿಂದಲೇ ಎಲ್ಲಾ ಜೀವಿಗಳು\nರೂಪುಗೊಂಡಿವೆ ಎಂದು ತಿಳಿ. ನಾನೇ ಜಗದ ಎಲ್ಲಾ ಹುಟ್ಟು -ಸಾವುಗಳಿಗೆ ಕಾರಣನಾಗಿದ್ದೇನೆ.\n\nಜಡ ಪ್ರಕೃತಿ ಮತ್ತು ಚಿತ್‌ ಪ್ರಕೃತಿ ಇವೇ ಇಡೀ ಜಗತ್ತಿನ ಎಲ್ಲಾ ಜೀವಜಾತಕ್ಕೆ ಮೂಲ ಕಾರಣ. ಭಗವಂತ\nಜೀವಜಾತದ ಹಿಂದೆ ತಂದೆಯಾಗಿ, ಲಕ್ಷ್ಮೀದೇವಿ ತಾಯಿಯಾಗಿ ನಿಂತು ಈ ಜಗತ್ತನ್ನು ಸೃಷ್ಟಿ ಮಾಡಿದರು.\nತಾಯಿಯ ಗರ್ಭದಲ್ಲಿ ಬೆಳೆಯುವ ಭ್ರೂಣದಂತೆ ಜಡಪ್ರಕೃತಿ ವಿಕಾರಗೊಂಡಿತು. ಹೀಗೆ ಚಿತ್‌ ಪ್ರಕೃತಿ ಜಡ\nಪ್ರಕೃತಿಗೆ ರೂಪ ಕೊಟ್ಟಳು, ಕೊಟ್ಟು ಧಾರಣೆ ಮಾಡಿದಳು, ಅದೇ ಜಗತ್ತಾಯಿತು.\n\nಭಗವಂತನ ಶಕ್ತಿ ಆಧಾನದಿಂದ, ಪ್ರೇರಣೆಯಿಂದ, ಜಡ ಮತ್ತು ಚಿತ್‌ ಪ್ರಕೃತಿಯ ಮೂಲಕ ಈ ಜಗತ್ತಿನ ಹುಟ್ಟಿಗೆ\nಭಗವಂತ ಹೇಗೆ ಕಾರಣನೋ, ಹಾಗೇ ಇಡೀ ಜಗತ್ತಿನ ಪ್ರಳಯ ಕೂಡಾ ಭಗವಂತ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ ಸಮಸ್ತ\nಜಗತ್ತಿನ ಉತ್ಪತ್ತಿಗೆ ಮೂಲ ಕಾರಣ ನಾನು, ಜಗತ್ತಿನ ಸಂಹಾರಕ್ಕೆ ಕಾರಣ ನಾನು” ಎಂದು. ಈ ಜಗತ್ತಿನ ಹುಟ್ಟಿನ\nಮೊದಲಿದ್ದವ, ಹುಟ್ಟಿಗೆ ಕಾರಣ, ಸಂಹಾರಕ್ಕೆ ಕಾರಣ, ಸಂಹಾರದ ನಂತರ ಇರುವವ ಆ ಭಗವಂತ.\n\nನಮ್ಮಲ್ಲಿ ಕೆಲವರು ಕೇಳುವುದಿದೆ: ಜಡಪ್ರಕೃತಿಗೆ ನಿಯಾಮಕ ಶಕ್ತಿ- ಚೇತನಪ್ರಕೃತಿ, ಚೇತನ ಪ್ರಕೃತಿಯನ್ನು\nಪ್ರೇರಣೆ ಮಾಡಿ ಸೃಷ್ಟಿ ಸಂಹಾರದಲ್ಲಿ ತೊಡಗಿಸುವವ “ಪುರುಷ' ನಾಮಕ ಭಗವಂತ. ಹಾಗಾದರೆ ಈ\nಭಗವಂತನನ್ನು ನಿಯಂತ್ರಿಸುವವರು ಯಾರು? ಎಂದು. ಇದಕ್ಕೆ ಕೃಷ್ಣ ಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ಉತ್ತರಿಸುತ್ತಾನೆ.",
  "7.7": "ಮತ್ತಃ ಪರತರಮ್ ನ ಅನ್ಯತ್ ಕಿಂಚಿತ್ ಅಸ್ತಿ ಧನಂಜಯ |\nಮಯಿ ಸರ್ವಮ್ ಇದಮ್ ಪ್ರೋತಮ್ ಸೂತ್ರೇ ಮಣಿಗಣಾಃ ಇವ -- ಧನಂಜಯಾ, ನನ್ನಲ್ಲದೆ ಇನ್ನೊಂದು ಪರತರ ವಸ್ತು ಇಲ್ಲ. ಎಲ್ಲವೂ ನನ್ನಲ್ಲೇ ಹೆಣೆದುಕೊಂಡಿದೆ — ದಾರದಲ್ಲಿ ಮಣಿಗಳ ರಾಶಿ ಹೇಗೆ ಹಾಗೆ.\n\nಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: \"ನನ್ನನ್ನು ಮೀರಿ ನನ್ನಿಂದ ಹಿರಿದಾದ, ನನಗಿಂತ ಬೇರೆಯಾದ ಇನ್ನೊಂದು ವಸ್ತುವಿಲ್ಲ\" ಎಂದು. ಚಿತ್ ಪ್ರಕೃತಿ, ಜಡ ಪ್ರಕೃತಿ, ಇದರಿಂದ ದೇಹ ಧಾರಣೆ ಮಾಡಿದ ಜೀವಜಾತ, ವಾಸಿಸುವ ಬ್ರಹ್ಮಾಂಡ, ಈ ಪಿಂಡಾಂಡ, ಎಲ್ಲವೂ ಕೂಡಾ ಭಗವಂತನಲ್ಲಿ ದಾರದಲ್ಲಿ ಮಣಿಗಳು ಹೆಣೆದುಕೊಂಡಂತೆ ಹೆಣೆದುಕೊಂಡಿವೆ. ಇಡೀ ವಿಶ್ವವನ್ನು, ಜೀವಜಾತವನ್ನು ಹೆಣೆದ ಸೂತ್ರ ಆ ಭಗವಂತ.",
  "7.8": "ರಸಃ ಅಹಮ್‌ ಅಪ್ಸು ಕೌಂತೇಯ ಪ್ರಭಾ ಅಸ್ಮಿ ಶಶಿ ಸೂರ್ಯಯೋಃ |\n\nಪ್ರಣವಃ ಸರ್ವವೇದೇಷು ಶಬ್ದಃ ಖೇ ಪೌರುಷಮ್‌ ನೃಷು - ಕೌಂತೇಯಾ ನೀರಿನಲ್ಲಿ ರಸವಿರುವುದು\nನನ್ನಿಂದ[ನೀರಿನಲ್ಲಿದ್ದು ರಸದ ಸವಿಯನ್ನುಣ್ಣಿಸುವುದರಿಂದ 'ರಸ' ನಾಮಕ.] ಚಂದ್ರ-ಸೂರ್ಯರಲ್ಲಿ ಬೆಳಕಿರುವುದು\nನನ್ನಿಂದ [ಚಂದ್ರ -ಸೂರ್ಯರಲ್ಲಿದ್ದು ಬೆಳಗಿಸುವುದರಿಂದ “ಪ್ರಭಾ' ನಾಮಕ.]ಎಲ್ಲಾ ವೇದಗಳಲ್ಲಿ 'ಓಂಕಾರ'\nಸಾರವಾದದ್ದು ನನ್ನಿಂದ.[ಎಲ್ಲಾ ವೇದಗಳಲ್ಲಿದ್ದು ನಾನೇ ಸ್ತುತಿಸುವುದರಿಂದ “ಪ್ರಣವ' ನಾಮಕ] ಆಗಸದಲ್ಲಿ ಸದ್ದು\nಮೂಡುವುದು ನನ್ನಿಂದ [ಆಗಸದಲ್ಲಿ ಸದ್ದು ಹೊರಡಿಸುವುದರಿಂದ “ಶಬ್ದ' ನಾಮಕ.] ಗಂಡಸರಲ್ಲಿ ಬೀರ\nನನ್ನಿಂದ[ಗಂಡಸರಲ್ಲಿದ್ದು ಬೀರವನ್ನಿತ್ತುದರಿಂದ 'ಪೌರುಷ' ನಾಮಕ].\n\nಭಗವಂತ ಈ ಪ್ರಪಂಚವನ್ನು ಸೃಷ್ಟಿ ಮಾಡಿದ, ಆನಂತರ ಪ್ರಪಂಚದೊಳಗೆ ಪ್ರವೇಶ ಮಾಡಿದ ಎನ್ನುವುದನ್ನು\nಶಾಸ್ತ್ರಗಳು ಹೇಳುತ್ತವೆ. ಇಲ್ಲಿ ನಮಗೆ ಸ್ವಲ್ಪ ಗೊಂದಲವಾಗುತ್ತದೆ. “ಭಗವಂತ ಸರ್ವವ್ಯಾಪ್ತ, ಆತ ಪ್ರವೇಶ\nಮಾಡುವುದು ಅಂದರೇನು?” ಇದು ನಮ್ಮ ಪ್ರಶ್ನೆ. ಇದು ಅರ್ಥವಾಗಬೇಕಾದರೆ ಸರ್ವವ್ಯಾಪ್ತ ಭಗವಂತನಿಗೆ\nಅನಂತ ರೂಪ ಎನ್ನುವ ವಿಚಾರವೂ ನಮಗೆ ತಿಳಿದಿರಬೇಕು. ಆತ ವ್ಯಾಪ್ತವಾದ ಒಂದು ರೂಪದಲ್ಲಿ ಸರ್ವತ್ರ\nಇದ್ದಾನೆ ಮತ್ತು ಒಂದೊಂದು ವಸ್ತುವಿನಲ್ಲೂ ವಿಶೇಷ ಶಕ್ತಿಪ್ರದನಾಗಿ, ವಿಶೇಷ ಶಕ್ತಿ ಅಭಿವ್ಯಂಜಕನಾದ ಒಂದು\nವಿಭೂತಿ ರೂಪದಲ್ಲಿ ಅಲ್ಲಿ ಪ್ರವೇಶ ಮಾಡುತ್ತಾನೆ. ಹೀಗೆ ಒಂದು ವಸ್ತುವಿನಲ್ಲೇ ಭಗವಂತನ ಅನೇಕ\nರೂಪಗಳಿರಬಹುದು. ಒಂದು ವಸ್ತುವಿಗೆ ಆ ಶಕ್ತಿವಿಶೇಷವನ್ನು ಕೊಟ್ಟ ಭಗವಂತನ ರೂಪವನ್ನು ಆತನ ವಿಭೂತಿ\nರೂಪ ಎನ್ನುತ್ತಾರೆ. ಇದು ಅವನ ಲೀಲೆ. ಭಗವಂತ ವಿಭೂತಿ ರೂಪದಲ್ಲಿ ಒಂದು ವಸ್ತುವಿನೊಳಗೆ ಪ್ರವೇಶಿಸಿ, ಆ\nವಸ್ತುವಿನಲ್ಲಿ ಒಂದು ಶಕ್ತಿವಿಶೇಷವನ್ನು ಅಭಿವ್ಯಕ್ತಗೊಳಿಸುತ್ತಾನೆ-ಇದು ವಿಭೂತಿ ವಿಜ್ಞಾನ.\n\nಈ ಶ್ಲೋಕದ ಪ್ರಾರಂಭದಲ್ಲಿ ಕೃಷ್ಣ ಪಂಚಭೂತಗಳಲ್ಲಿ ಬಹಳ ಮುಖ್ಯವಾದ ನೀರಿನಲ್ಲಿನ ತನ್ನ ವಿಭೂತಿಯನ್ನು\nವಿವರಿಸುತ್ತಾನೆ. ನಮ್ಮ ಉಪಾಸನೆಯಲ್ಲಿ ಭಗವಂತನನ್ನು ಜಲದಲ್ಲಿ ಉಪಾಸನೆ ಮಾಡುವುದು ಬಹಳ ವಿಶೇಷ.\nಎಲ್ಲಾ ಅನುಷ್ಠಾನಕ್ಕೂ(ಸ್ನಾ ನ, ಅರ್ಗ್ಯ, ತರ್ಪಣ ಇತ್ಯಾದಿ) ಕೂಡಾ ಬೇಕಾಗಿರುವುದು ನೀರು. ಅರ್ಥ್ಯಂ\nಸಮರ್ಪಯಾಮಿ। ಗಂದಾಕ್ಷತಂ ಸಮರ್ಪಯಾಮಿ। ಪುಷ್ಪಂ ಸಮರ್ಪಯಾಮಿ। ನೈವೇದ್ಯಂ ಸಮರ್ಪಯಾಮಿ।\nತಾಂಬೂಲಂ ಸಮರ್ಪಯಾಮಿ। ಎಂದು ಸಮರ್ಪಣೆ ಮಾಡುವುದು ಒಂದು ಉದ್ಧರಣೆ ನೀರನ್ನು! ಹೀಗೆ ಏನೂ\nಇಲ್ಲದಾಗ ಎಲ್ಲವುದಕ್ಕೂ ಪ್ರತಿನಿಧಿಯಾಗಿ ನೀರನ್ನು ಅರ್ಪಿಸುತ್ತೇವೆ. ಏಕೆಂದರೆ ಭಗವಂತನ ಸೃಷ್ಟಿಯ ವಿಸ್ತಾರಕ್ಕೆ\nನೀರು ಮೂಲದ್ರವ್ಯ. ಅದನ್ನು ಭಕ್ತಿಯಿಂದ ಅರ್ಪಿಸಿದರೆ ಎಲ್ಲವನ್ನು ಅರ್ಪಿಸಿದಂತೆ.\n\nಇಲ್ಲಿ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ರಸಃ ಅಹಮ್‌ ಅಪ್ಸು ಕೌಂತೇಯ” ಎಂದು. ಅಂದರೆ “ರಸ ನಾಮಕನಾಗಿ ನೀರಿನಲ್ಲಿ\nನಾನು ರಸವಾಗಿದ್ದೇನೆ” ಎಂದು. ಸಂಸ್ಕೃತದಲ್ಲಿ ರಸ ಎಂದರೆ ಸಾರಭೂತವಾದದ್ದು, ಹರಿಯುವಿಕೆ, ಇತ್ಯಾದಿ\n\nಅನೇಕ ಅರ್ಥಗಳಿವೆ. ಹರಿಯುವ ಶಕ್ತಿ ನೀರಿನ ವಿಶಿಷ್ಟ ಗುಣ. ಹರಿಯುವ ಶಕ್ತಿಯಾಗಿ \"ಹರಿ'\nನೀರಿನಲ್ಲಿ ಕುಳಿತಿರುವುದರಿಂದ ನೀರಿಗೆ ಆ ಶಕ್ತಿ ಬಂತು. ಉಪಾಸನೆಯಲ್ಲಿ ಈ ಜ್ಞಾನ ಬಹಳ ಮುಖ್ಯ.\nಶಾಸ್ತ್ರೀಯವಾಗಿ ಗುಹ್ಯ ಭಾಷೆಯಲ್ಲಿ ನೀರಿಗೆ “ವಿಷ್ಣುಃ ಎನ್ನುತ್ತಾರೆ. “ವಿಷಂತಿ ಅತ್ರ ಇತಿ ವಿಷ್ಣುಃ- ಅಂದರೆ\nಯಾವುದರ ಒಳಗೆ ಹೋಗಿ ಹೊರಗೆ ಬರಲು ಸಾಧ್ಯವೋ ಅದು ವಿಷ್ಣುಃ.\n\nಭಗವಂತ ನೀರಿನಲ್ಲಿ ರಸವಾಗಿ(ರುಚಿಯಾಗಿ) ಕುಳಿತ. ನಮಗೆ ರುಚಿಯ ಅನುಭವವನ್ನು ಕೊಟ್ಟು ಅವನು\nನೀರಿನಲ್ಲಿ ರಸವಾಗಿ ಕೂರದೇ ಇದ್ದಿದ್ದರೆ ನಮಗೆ ನಾಲಿಗೆ ಇದ್ದೂ ಏನೂ ಉಪಯೋಗವಾಗುತ್ತಿರಲಿಲ್ಲ.\nಪ್ರತಿಯೊಂದರಲ್ಲೂ ಸಾರಭೂತವಾದ ಇಂತಹ ಅಸಾಧಾರಣ ಶಕ್ತಿ ಏನಿದೆ-ಅದು ಆ ಭಗವಂತನ ವಿಭೂತಿ. ಆತ\nರಸಃ-“ರ' ಎಂದರೆ ಆನಂದ ; \"ಸ' ಎಂದರೆ ಜ್ಞಾನ-ಆದ್ದರಿಂದ ರಸಃ ನಾಮಕ ಭಗವಂತ ಜ್ಞಾನಾನಂದಪೂರ್ಣ.\nನೀರಿನ ನಂತರ ಕೃಷ್ಣ ಸೂರ್ಯ ಮತ್ತು ಚಂದ್ರನ ಉದಾಹರಣೆಯನ್ನು ತೆಗೆದುಕೊಳ್ಳುತ್ತಾನೆ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ-\n“ಪ್ರಭಾ ಅಸ್ಮಿ ಶಶಿ ಸೂರ್ಯಯೋಃ” ಎಂದು. ಅಂದರೆ “ಸೂರ್ಯ ಚಂದ್ರರೊಳಗೆ ಪ್ರಭಾ ನಾಮಕನಾಗಿದ್ದು\nಬೆಳಗಿಸುವವ ನಾನು”. ನಮಗೆ ಪ್ರಾಣಶಕ್ತಿ ಹರಿದು ಬರುವುದು ಸೂರ್ಯ ಮತ್ತು ಚಂದ್ರನಿಂದ. ಮನುಷ್ಯನ\nಜೀವನಕ್ಕೆ ವಿಶೇಷವಾಗಿ ಸೌರಶಕ್ತಿ ಕಾರಣವಾದರೂ ಕೂಡಾ ಸಮಸ್ತ ವನಸ್ಪತಿಗಳಿಗೆ ಚಂದ್ರನ ವಿಶೇಷ\nಸಂಬಂಧವಿದೆ. ಈ ಕಾರಣಕ್ಕಾಗಿ ವನಸ್ಪತಿ ತಜ್ಞರು ಯಾವ ಯಾವ ಮರದಲ್ಲಿ ಎಂತೆಂತಾ ಶಕ್ತಿ ಬೆಳದಿಂಗಳಿಂದ\nನಿಷ್ಪನ್ನವಾಗುತ್ತದೆ. ಎನ್ನುವುದನ್ನು ಅಧ್ಯಯನ ಮಾಡಿ ಚಂದ್ರನ ಗತಿಗನುಗುಣವಾಗಿ ವನಸ್ಪತಿಗಳನ್ನು\nಕತ್ತರಿಸುತ್ತಿದ್ದರು. ಹಿಂದಿನ ಕಾಲದಲ್ಲಿ ಮನೆ ಕಟ್ಟಲು ಬಳಸುವ ಮರವನ್ನು ಚಂದ್ರನ ಗತಿಗನುಗುಣವಾಗಿ\nಅಧ್ಯಯನ ಮಾಡಿ ಕತ್ತರಿಸುತ್ತಿದ್ದರು. ಇದನ್ನು ತಿಳಿಯದೇ ಮರವನ್ನು ಕತ್ತರಿಸಿದರೆ ಆ ಮರ ಬಾಳಿಕೆ ಬಾರದು.\nಭಗವಂತ ಚಂದ್ರ ಸೂರ್ಯರಿಂದ ನಿರಂತರ ಶಕ್ತಿ ಹರಿಸುವುದರಿಂದ ಈ ಜೀವಲೋಕ ಬದುಕಿದೆ. ಸೂರ್ಯ\nಚಂದ್ರರ ಶಕ್ತಿಪಾತವಾಗದೇ ಇದ್ದರೆ ನಮಗೆ ಬದುಕೇ ಇಲ್ಲ. ಇದಕ್ಕಾಗಿ ಭಗವಂತನನ್ನು “ಕೇಶವ' ಎನ್ನುತ್ತಾರೆ.\nಸೂರ್ಯ ಚಂದ್ರರ ಕಿರಣದಲ್ಲಿದ್ದು, ಆ ಪ್ರಕಾಶದ ಮೂಲಕ, ಬಿಸಿಲು ಮತ್ತು ಬೆಳದಿಂಗಳ ಮೂಲಕ ನಮಗೆ\nಬದುಕನ್ನು ಕೊಡುವವ ಕೇಶವ. ಚಂದ್ರನ ಬೆಳಕಿನಲ್ಲಿ, ಸೂರ್ಯನ ಬೆಳಕಿನಲ್ಲಿ ಆ ಬೆಳಗುವ ಶಕ್ತಿಯನ್ನು ಕೊಟ್ಟು, ಆ\nಬೆಳಕಿನಲ್ಲಿ ಬೆಳಕಾಗಿ 'ಪ್ರಭಾ' ಶಬ್ದವಾಚ್ಯ ಭಗವಂತ ಕೂತಿದ್ದಾನೆ. 'ಪ್ರ' ಎಂದರೆ ಪ್ರಕೃಷ್ಣವಾದ, 'ಭ' ಎಂದರೆ\nಜ್ಞಾನಾನಂದಮಯವಾದ. ಭಗವಂತ ಜ್ಞಾನಾನಂದಮಯವಾದ ಬೆಳಕಾಗಿ. ಸೂರ್ಯ ಚಂದ್ರರಲ್ಲಿದ್ದು\nಜೀವಜಾತಕ್ಕೆ ನಿರಂತರ ಪ್ರಾಣಶಕ್ತಿಯನ್ನು ಹರಿಸುತ್ತಿದ್ದಾನೆ.\n\nಕೃಷ್ಣ ಮುಂದುವರಿದು ಹೇಳುತ್ತಾನೆ: “ಎಲ್ಲಾ ವೇದಗಳಲ್ಲೂ, ವೇದ ಶಬ್ದ ವಾಚ್ಯನಾಗಿ ನಾನು ತುಂಬಿದ್ದೇನೆ”\nಎಂದು. 'ವೇದ' ಎಂದರೆ 'ಅರಿವು ಕೊಡುವಂತಾದ್ದು' ಎಂದರ್ಥ. ಎಲ್ಲರಿಗೂ ಅರಿವು ಕೊಡುವವ ಭಗವಂತ.\nಸ್ವಯಂ ಪೂರ್ಣನಾಗಿ ಸರ್ವರಿಗೂ ಜ್ಞಾನಪ್ರದನಾಗಿ, ಸರ್ವಶಬ್ದವಾಚ್ಯನಾಗಿ, ಸರ್ವ ವೇದಗಳಲ್ಲಿ ಭಗವಂತ\nನೆಲೆಸಿದ್ದಾನೆ. ವೇದದ ಅರ್ಥ ತಿಳಿದವನ ಬದುಕು ಸದಾ ಮಂಗಳಮಯ. ಅಂತಹ ವೇದದ ಸಾರ 'ಓಂಕಾರ”-\nಅದೇ ಪ್ರಣವಃ.\n\nಇಲ್ಲಿ ನಾವು ಒಂದು ವಿಷಯವನ್ನು ಅರ್ಥ ಮಾಡಿಕೊಳ್ಳಬೇಕು. ಓಂಕಾರ ಸರ್ವ ವೇದಗಳ ಸಾರ ಎನ್ನುತ್ತಾರೆ.\nಅದು ಹೇಗೆ ಎಂದು. ವೇದಗಳು ಅನೇಕ. ಋಗ್ವೇದದಲ್ಲಿ 24 ಶಾಖೆ, ಯಜುರ್ವೇದದಲ್ಲಿ 101 ಶಾಖೆ,\nಸಾಮವೇದದಲ್ಲಿ 1000 ಶಾಖೆ, ಅಥರ್ವವೇದದಲ್ಲಿ 12 ಶಾಖೆ. ಹೀಗೆ ಒಟ್ಟು 1137 ಸಂಹಿತೆಗಳು. ಅದಕ್ಕೆ ಅಷ್ಟೆ 6\n\nಬ್ರಾಹ್ಮಣಗಳು, ಅರಣ್ಯಕಗಳು, ಉಪನಿಷತ್ತುಗಳು. ಹೀಗೆ ವೇದವೆಂದರೆ ವಿಪುಲವಾದ ವೈದಿಕ ವಾಜ್ಮಯ. ಎಷ್ಟೆ 6\nವೇದಗಳಿದ್ದರೂ ಕೂಡಾ ಮೂಲತಃ ವೇದದಲ್ಲಿ ಪ್ರಮುಖವಾಗಿ ಮೂರು ವಿಭಾಗವಿದೆ. ಪದ್ಯರೂಪ(ಋಗ್ವೇದ),\nಗದ್ಯರೂಪ(ಯಜುರ್ವೇದ) ಮತ್ತು ಗಾನರೂಪ(ಸಾಮವೇದ). ಈ ಮೂರು ವೇದಗಳ ಮೂರು ಅಕ್ಷರಗಳನ್ನು\nತೆಗೆದುಕೊಂಡು ನಿರ್ಮಾಣವಾಗಿರುವುದು ಓಂಕಾರ. “ಓಂಕಾರಕ್ಕೆ ಸಾರತ್ವವನ್ನು ಕೊಟ್ಟು ಸಾರಭೂತನಾಗಿ\n'ಪ್ರಣವಃ' ಶಬ್ದವಾಚ್ಯನಾಗಿ ನಾನು ಓಂಕಾರದಲ್ಲಿ ನೆಲೆಸಿದ್ದೇನೆ” ಎನ್ನು ತ್ತಾನೆ ಕೃಷ್ಣ. ಇದು ಬಹಳ ವಿಚಾರಗರ್ಭಿತ\nಸಂಗತಿ. ಪ್ರಾಚೀನರು ಮೂರು ವೇದಗಳನ್ನು ಭಟ್ಟಿ ಇಳಿಸಿ ಅದರ ಸಾರವಾದ ಮೂರು ವರ್ಗಗಳ ಒಂದು ಸೂಕ್ತ\nಮಾಡಿದರು. ಅದೇ ಪುರುಷಸೂಕ್ತ. ಈ ಕಾರಣದಿಂದ ವೇದಸೂಕ್ತಗಳಲ್ಲೇ ಪುರುಷಸೂಕ್ತ ಅತ್ಯಂತ ಶ್ರೇಷ್ಠವಾದ\nಸೂಕ್ತ. ಈ ಸೂಕ್ತವನ್ನು ಮತ್ತೆ ಭಟ್ಟಿಇಳಿಸಿ ಮೂರು ಪಾದಗಳ ಗಾಯತ್ರಿ ಮಂತ್ರ(ತತ್ಸವಿತುರ್ವರೇಣ್ಯಂ ಭರ್ಗೋ\nದೇವಸ್ಯ ಧೀಮಹಿ ಧಿಯೋ ಯೋನಃ ಪ್ರಚೋದಯಾತ್‌) ನಿರ್ಮಾಣವಾಯಿತು. “ತತ್‌ ಸವಿತುರ್‌ ವರೇಣ್ಯಂ'\nಋಗ್ವೇದಕ್ಕೆ ಸಂಬಂಧಪಟ್ಟದ್ದು, “ಭರ್ಗೋ ದೇವಸ್ಯ ಧೀಮಹಿ' ಯಜುರ್ವೇದಕ್ಕೆ ಸಂಬಂಧಪಟ್ಟದ್ದು, \"ಧರೀಯೊ ಯೊ\nನಃ ಪ್ರಚೋದಯಾತ್‌' ಸಾಮವೇದಕ್ಕೆ ಸಂಬಂಧಪಟ್ಟದ್ದು. ಹೀಗೆ ಮೂರು ವೇದಗಳ ಸಾರ ಗಾಯತ್ರಿಯ\nಮೂರುಪಾದಗಳುಳ್ಳ ಒಂದು ಮಂತ್ರದಲ್ಲಿದೆ. ಇದಕ್ಕಾಗಿ ಗಾಯತ್ರಿ ಮಂತ್ರವನ್ನು 'ವೇದಮಾತ' ಎನ್ನುತ್ತಾರೆ. ಈ\nಗಾಯತ್ತಿಯಿಂದ ರಸ ತೆಗೆದಾಗ ಮೂರು ಪಾದಗಳಿಂದ ಮೂರು ಪದಗಳುಳ್ಳ ವ್ಯಾಹೃತಿ “ಭೂಃ ಭುವಃ ಸ್ವಃ”; ಈ\nಮೂರು ಪದಗಳ ಸಾರ ಮೂರು ಅಕ್ಷರದ(ಅ, ಉ, ಮ) ಓಂಕಾರ-,\n\nಓಂಕಾರದಲ್ಲಿ “ಅ'ಕಾರ ಋಗ್ವೇದಕ್ಕೆ, \"ಉ'ಕಾರ ಯಜುರ್ವೇದಕ್ಕೆ ಮತ್ತು 'ಮ'ಕಾರ ಸಾಮವೇದಕ್ಕೆ\nಸಂಬಂಧಪಟ್ಟ ದ್ದು. ಋಗ್ವೇದ \" ಅಗ್ನಿ ಮೀ”ಳೇ ಪುರೋಹಿತಂ ಯಜ್ಞಸ್ಯ ದೇವಮೃತ್ವಿಜಂ” | ಹೋತಾ”ರಂ ರತ್ನ\nಧಾತಮಂ |...” ಎಂದು “ಅ' ಕಾರದಿಂದ ಪ್ರಾರಂಭವಾಗುತ್ತದೆ. ಮತ್ತು “...ಸಮಾನೀ ವ ಆಕೂತಿಃ ಸಮಾನಾ\nಹೃದಯಾನಿ ಹಃ: | ಸಮಾನಮಸ್ತು ವೋ ಮನೋ ಯಥಾ ವಃ ಸುಸಹಾಸತಿ ॥” ಎಂದು “ಇ'ಕಾರದಲ್ಲಿ\nಕೊನೆಗೊಳ್ಳುತ್ತದೆ. ಅಲ್ಲಿಂದ ಮುಂದುವರಿದು ಯಜುರ್ವೇದ “ಇಷೇ ತ್ವೋರ್ಜೆ ತ್ವಾ ..” ಎಂದು \"ಇ'ಕಾರದಿಂದ\nಪ್ರಾರಂಭವಾಗಿ “......ಸಮುದ್ರೋ ಬಂಧುಃ” ಎಂದು \"ಉ'ಕಾರದಲ್ಲಿ ಕೊನೆಗೊಳ್ಳುತ್ತದೆ. ಹೀಗೆ ಓಂಕಾರದಲ್ಲಿನ\n\"ಅ'ಕಾರ ಮತ್ತು \"ಉ'ಕಾರ ಋಗ್ವೇದ ಮತ್ತು ಯಜುರ್ವೇದವನ್ನು ಪೂರ್ಣವಾಗಿ ಸೂಚಿಸುವ\nಸಂಕ್ಷೇಪಣಾ(abbreviation)ರೂಪ. ಇಲ್ಲಿಂದ ಮುಂದೆ ಸಾಮವೇದ. ಸಾಮವೇದ “ಅಗ್ನ ಆ ಯಾಹಿ .......೫\nಎಂದು “ಅ'ಕಾರದಿಂದ ಆರಂಭವಾಗಿಬ್ರಸ್ಪತಿರ್ದಧಾತು” ಎಂದು \"ಉ'ಕಾರದಲ್ಲಿ ಕೊನೆಗೊಳ್ಳುತ್ತದೆ.\nಆದ್ದರಿಂದ ಇಲ್ಲಿ “ಮ' ಕಾರ ಬಂದಿಲ್ಲ. ಆದರೆ ನಮಗೆ ತಿಳಿದಂತೆ ಸಾಮವೇದ ನಾದ ರೂಪದಲ್ಲಿದೆ. ಓಂಕಾರದಲ್ಲಿ\nಕೂಡಾ \"ಮ' ಎನ್ನುವುದು ನಾದರೂಪದಲ್ಲಿ ಹೊರ ಹೊಮ್ಮುವ ಅಕ್ಷರ- ಅದು ಸಂಗೀತ. ಹೀಗೆ ಓಂಕಾರ ವೇದದ\nಸಂಕ್ಷೇಪಣಾರೂಪವಾದ ಬೀಜಾಕ್ಷರ. ಇದು ನಮಗೆ ವೇದವನ್ನು ಗುರುತಿಸುವ ಮಾರ್ಗದರ್ಶಿ. ಆದ್ದರಿಂದ ಇದು\nಭಗವಂತನನ್ನು ಸ್ತೋತ್ರ ಮಾಡುವ ಮಂತ್ರಗಳಲ್ಲಿ ಅತ್ಯಂತ ಪ್ರಕೃಷ್ಣವಾದುದ್ದು. ಇದಕ್ಕಿಂತ ದೊಡ್ಡ\nಸ್ತೋತ್ರಮಾಡುವ ಶಬ್ದ ಈ ಪ್ರಪಂಚದಲ್ಲಿಲ್ಲ.\n\nಒಂದು ಮಂತ್ರದ ಕೊನೆಯಲ್ಲಿ ಹೇಳುವ ಓಂಕಾರಕ್ಕೆ ವ್ಯಾಕರಣದ ಪರಿಭಾಷೆಯಲ್ಲಿ 'ಪ್ರಣವಃ' ಎನ್ನುತ್ತಾರೆ.\nಆದಿಯಿಂದ ಅಂತದ ತನಕ ಸಮಸ್ತ ನಾಮ ಪ್ರತಿಪಾದ್ಯ 'ಭಗವಂತ' ಎಂದು ತೋರಿಸುವುದಕ್ಕೆ ಓಂಕಾರವನ್ನು\nಆದಿ-ಅಂತದಲ್ಲಿ ಉಚ್ಛಾರ ಮಾಡುತ್ತಾರೆ. ಈ ಕಾರಣಕ್ಕಾಗಿ ಮಂತ್ರದ ಆದಿಯಲ್ಲಿ ಮತ್ತು ಅಂತದಲ್ಲಿ ಬಳಸುವ\n\nಓಂಕಾರವನ್ನು ಎಂದೂ ಪ್ರತ್ಯೇಕವಾಗಿ ಹೇಳಬಾರದು. ಉದಾಹರಣೆಗೆ ವಿಷ್ಣು ಸಹಸ್ರನಾಮದ ಕೊನೆಯಲ್ಲಿ\n“ಸರ್ವಪ್ರಹರಣಾಯುಧಃ ಓಂ ನಮಃ ಇತಿ” ಎಂದು ಹೇಳದೆ “ಸರ್ವಪ್ರಹರಣಾಯುಧೋಂ ನಮಃ ಇತಿ” ಎಂದು\nಹೇಳಬೇಕು. ಆಯುಧಃ ಎನ್ನುವಲ್ಲಿನ ವಿಸರ್ಗ(ಃ)ವನ್ನು ತೆಗೆದು ಅಲ್ಲಿ \"ಓಂ' ಸೇರಿಸಿ ಅದನ್ನು ಸಮಸ್ತವಾಗಿ\nಹೇಳಬೇಕು.\n\n“ವೇದದ ಸಾರಭೂತವಾದ 'ಪ್ರಣವಃ' ನಾನು” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಪ್ರಣವಃ ವಿಸ್ತಾರವಾದಾಗ ವ್ಯಾಹೃತಿ,\nವ್ಯಾಹೃತಿ ವಿಸ್ತಾರವಾಗಿ ಗಾಯತ್ರಿ, ಗಾಯತ್ರಿ ವಿಸ್ತಾರವಾಗಿ ಕುರುಡ ಸೂಕ್ತ, ನಂತರ ಮೂರು ವೇದಗಳು,\nಅಲ್ಲಿಂದ ಸಮಸ್ತ ವೇದಗಳು. ಹೀಗೆ ಪ್ರಣವದಲ್ಲಿ, ವ್ಯಾಹೃತಿಯಲ್ಲಿ, ಪುರುಷ ಸೂಕ್ತದಲ್ಲಿ, ಸಮಸ್ತವೇದಗಳಲ್ಲಿ\nಭಗವಂತ ನೆಲೆಸಿದ್ದಾನೆ.\n\nವೇದದ ಶಬ್ದಗಳಿಂದಲೇ ಹುಟ್ಟಿ ಬಂದ ಪ್ರಪಂಚದ ಎಲ್ಲಾ ಶಬ್ದದಲ್ಲೂ, ಎಲ್ಲಾ ಲೌಕಿಕ ನಾದದಲ್ಲೂ ತುಂಬಿದ\nಭಗವಂತ, ಆಕಾಶದಲ್ಲಿ ಅನಂತ ಶಬ್ದಗಳನ್ನೂ, ಅನಂತ ನಾದಗಳನ್ನೂ ಸೃಷ್ಟಿ ಮಾಡಿದ. ನಮಗೆ ಶಬ್ದದಿಂದ\nಅನಂತ ಅನುಭವವನ್ನು ಕೊಟ್ಟು, ಆ ಶಬ್ದವನ್ನು ಗ್ರಹಿಸುವ ಮತ್ತು ಗ್ರಹಿಸಿ ಪುನರುಚ್ಛರಿಸುವ ವಿಶೇಷ ಶಕ್ತಿಯನ್ನು\nಕರುಣಿಸಿದ. ಜ್ಞಾನದ ಮೂಲಕ ಈ ಶಬ್ದ ನಾಮಕ ಭಗವಂತನನ್ನು ತಿಳಿಯುವ ವಿಶೇಷ ಶಕ್ತಿ ಮಾನವನಿಗೆ\nಭಗವಂತನ ವಿಶೇಷ ಕೊಡುಗೆ. ಜೀವಲೋಕಕ್ಕೆ ನಾನಾ ವಿಧದ ಪೌರುಷವನ್ನು ಕೊಟ್ಟ ಭಗವಂತ, “ಪುರುಷ' ಶಬ್ದ\nವಾಚ್ಯನಾಗಿ ಮಾನವರ ಬಹುವಿಧ ಪೌರುಷದಲ್ಲಿ ತುಂಬಿದ.\n\nಮುಂದಿನ ಶ್ಲೋಕಕ್ಕೆ ಹೋಗುವ ಮುನ್ನ ಹಿಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ನಾವು ಸಂಕ್ಷಿಪ್ತವಾಗಿ ನೋಡಿದ 'ಓಂಕಾರದ' ಬಗ್ಗೆ\nಇನ್ನೂ ಹೆಚ್ಚಿನ ವಿವರವನ್ನೊಮ್ಮೆ ನೋಡೋಣ. ಹಿಂದೆ ಹೇಳಿದಂತೆ ಸಮಸ್ತ ವೇದದಲ್ಲಿ ನಾವು ಉಪಾಸನೆ\nಮಾಡುವ ಭಗವಂತನ ಎಲ್ಲಾ ಗುಣಗಳನ್ನು ಓಂಕಾರ ಹೇಳುತ್ತದೆ. ಓಂ(ತೌ) ಎನ್ನುವುದಕ್ಕೆ ಒಂದು ಅಖಂಡ\nಅರ್ಥವಿದೆ. ಓಂಕಾರ '“ಅವ' ಅಥವಾ 'ಉಯಿ' ಎನ್ನುವ ಎರಡು ಧಾತುವಿನಿಂದ ನಿಷ್ಠನ್ನವಾಯಿತು. \"ಅವತಿ ಇತಿ\nಓಂ'-ಇಲ್ಲಿ \"ಅವತಿ' ಪದಕ್ಕೆ ಅನೇಕ ಅರ್ಥವಿಶೇಷಗಳಿವೆ. \"ಅವ ವ್ಯಾಪ್ತೋ' ಧಾತು; ಅವತಿ ಎಂದರೆ ಎಲ್ಲಾ ಕಡೆ\nತುಂಬಿರುವ. ಆದ್ದರಿಂದ ಓಂ ಎಂದರೆ ಸರ್ವಗತ. 'ಅವ' ಎಂದರೆ ಜ್ಞಾನ. “ಅವತಿ' ಎಂದರೆ\nಎಲ್ಲವನ್ನೂ ತಿಳಿದವನು; ಆದ್ದರಿಂದ ಓಂ ಎಂದರೆ ಸರ್ವಜ್ಞ. 'ಅವ ಸಾಮರ್ಥ್ಯೇ' ಎಂದು\nಇನ್ನೊಂದು ಧಾತು; ಆದ್ದರಿಂದ ಅವತಿ ಎಂದರೆ ಸರ್ವಸಮರ್ಥ(omnipotent). ಹೀಗೆ ದೇವರು ಸರ್ವಸಮರ್ಥ,\nಸರ್ವಗತ, ಸರ್ವಜ್ಞ ಎನ್ನುವ ಪ್ರಮುಖ ಮೂರು ಮುಖವನ್ನು ಓಂಕಾರ ತಿಳಿಸುತ್ತದೆ. ಇದು ಭಗವಂತನನ್ನು\nಗುರುತಿಸುವ ಮೂರು ಮೂಲಭೂತ ಗುಣಗಳು. ಜೀವ “ಅಣು'ವಾದರೆ.. ಭಗವಂತ ಸರ್ವಗತ; ಜೀವ\nಅಲ್ಪಜ್ಞನಾದರೆ ಭಗವಂತ ಸರ್ವಜ್ಞ; ಜೀವ ಅಲ್ಪ ಸಾಮರ್ಥ್ಯ ಉಳ್ಳವನಾದರೆ ಭಗವಂತ ಸರ್ವಸಮರ್ಥ. ಹೀಗೆ\nತನ್ನಿಂದ ಭಿನ್ನವಾಗಿರುವ ಆ ಶಕ್ತಿ ಎಷ್ಟು ಭಿನ್ನ ಎನ್ನುವುದನ್ನು ಓಂಕಾರ ತಿಳಿಸುತ್ತದೆ.\n\n\"ಅವ ಪ್ರವೇಶೇ' ಎನ್ನುವ ಧಾತು- ಇಲ್ಲಿ ಅವತಿ ಎಂದರೆ “ಪ್ರವೇಶ ಮಾಡುತ್ತಾನೆ' ಎಂದರ್ಥ. ಭಗವಂತ ಸರ್ವಗತ,\nಆದ್ದರಿಂದ ಆತ ಎಲ್ಲರ ಒಳಗೂ(omnipresent) ಹೊರಗೂ ಇದ್ದಾನೆ. ಇದನ್ನು ನಾರಾಯಣ ಸೂಕ್ತದಲ್ಲಿ “ಅಂತರ್‌\nಬಹಿಶ್ಚ ತತ್‌ ಸರ್ವಂ ವ್ಯಾಪ್ಯ ನಾರಾಯಣ ಸ್ಥಿತಃ” ಎಂದಿದ್ದಾರೆ. \"ಅವ ವದೇ' ಅನ್ನು ವ ಇನ್ನೊಂದು ಧಾತುವಿದೆ.\nಅವತಿ ಎಂದರೆ ರಕ್ಷಣೆ ಮಾಡುವವ ಎನ್ನುವುದು ಒಂದು ಅರ್ಥ, ಸಂಹಾರ ಮಾಡುವವ ಎನ್ನುವುದು ಇನ್ನೊಂದು\nಅರ್ಥ. ಆದ್ದರಿಂದ ಓಂ ಎಂದರೆ ಸರ್ವರಕ್ಷಕ, ಸರ್ವಸಂಹಾರಕ ಶಕ್ತಿ. “ಭಗವಂತ ನಮ್ಮಲ್ಲಿರುವ ಅಜ್ಞಾನವನ್ನು,\n\nನಮ್ಮಲ್ಲಿರುವ ದುಃಖವನ್ನು, ನಮ್ಮಲ್ಲಿರುವ ದೋಷವನ್ನು ಸಂಹಾರ ಮಾಡತಕ್ಕವ- ಸರ್ವ ದೋಷ ನಾಶಕ”. ಇದು\nನಾವು ಓಂಕಾರದಲ್ಲಿ 'ಸಂಹಾರಕಶಕ್ತಿ' ಭಗವಂತನನ್ನು ಉಪಾಸನೆ ಮಾಡುವಾಗ ತಿಳಿದಿರಬೇಕಾದ ವಿಚಾರ.\nಸಮಷ್ಟಿಯಾಗಿ “ಅವ' ಧಾತುವಿನಿಂದ ಹುಟ್ಟಿದ ಓಂ- ಭಗವಂತ ಸರ್ವ ಸಂಹಾರಕ, ಸರ್ವ ದೋಷನಿವಾರಕ,\nಸರ್ವಾಂತರ್ಯಾಮಿ, ಸರ್ವಾಂತರ್ನಿಯಾಮಕ, ಸರ್ವಜ್ಞ, ಸರ್ವಸಮರ್ಥ, ಹೀಗೆ ನಾವು ಉಪಾಸನೆ\nಮಾಡಬೇಕಾದ ಭಗವಂತನ ಮುಖ್ಯ ಗುಣಗಳೆಲ್ಲವನ್ನೂ ಹೇಳುತ್ತದೆ. ಇದರ ವಿವರವೇ ಸಮಸ್ತ ವೇದದಲ್ಲಿ\nಬರುವಂತಾದ್ದು.\n\nಎರಡನೇ ಧಾತು \"ಊಯತೇ ಇತೀ ಓಂ'. ಜಗತ್ತು ಯಾರಲ್ಲಿ ಓತವಾಗಿದೆಯೋ ಅವನು ಓಂ. ಅಂದರೆ ಇಡೀ\nಜಗತ್ತು ಯಾರಲ್ಲಿ ಆಶ್ರಿತವಾಗಿದೆಯೋ ಅವನು 'ಓಂಕಾರ' ವಾಚ್ಯ ಭಗವಂತ. ಎಲ್ಲಾ ಗುಣಗಳು ಯಾರಲ್ಲಿ\nಓತವಾಗಿದೆಯೋ(ಹೆಣೆದುಕೊಂಡಿದೆಯೋ) ಅವನು ಓಂ. ಅಂದರೆ ಭಗವಂತ ಸರ್ವಾಧಾರ-ಸರ್ವಗುಣಪೂರ್ಣ.\n\nಓಂಕಾರವನ್ನು ಸಮಷ್ಟಿಯಾಗಿ ನೋಡಿದ ಮೇಲೆ ಅದನ್ನು ಬೇರೆ ಬೇರೆ ಅಕ್ಷರವಾಗಿ ವಿಂಗಡಿಸಿಕೊಂಡು,\nಅದರಲ್ಲಿರುವ ಮೂರು ಅಕ್ಷರ(ಅ, ಉ, ಮ)ಏನನ್ನು ಹೇಳುತ್ತದೆ ಎನ್ನುವುದನ್ನು ನೋಡೋಣ. ಪ್ರಣವ ಪದದ\nಒಂದೊಂದು ಅಕ್ಷರ ಓಂಕಾರದ ಒಂದೊಂದು ಅಕ್ಷರದ ವಿವರಣಾರೂಪದಲ್ಲಿದೆ. ಓಂಕಾರದ ಮೊದಲನೇ ಅಕ್ಷರ\n\"ಅ'. \"ಅ' ಅಂದರೆ ಅಧಿಕ, ಎಲ್ಲಕ್ಕಿಂತ ಅಧಿಕನಾದ ಭಗವಂತ “ಅ'. ಇದನ್ನು ಪ್ರಣವದ “ಪ್ರ' ಅಕ್ಷರ ವಿವರಿಸುತ್ತದೆ.\n'ಪ್ರ' ಎಂದರೆ ಪ್ರಕೃಷ್ಣವಾದ- ಎಲ್ಲಕ್ಕಿಂತ ಪ್ರಕೃಷ್ಣವಾದ ಅನಂತ ಶಕ್ತಿ ಭಗವಂತ \"ಅ'. ಓಂಕಾರದ ಎರಡನೇ ಅಕ್ಷರ\n\"ಉ'. \"ಉ' ಅಂದರೆ ಉತ್ತಮವಾದ, ಜ್ಞಾನಾನಂದದಿಂದ ತುಂಬಿ ಉನ್ನತವಾದದ್ದು. ಇದನ್ನು ಪ್ರಣವದ \"ಣ' ಅಕ್ಷರ\nವಿವರಿಸುತ್ತದೆ. \"ಇ' ಎಂದರೆ ಜ್ಞಾನಾನಂದದ ಆತ್ಮಬಲ. ಭಗವಂತ ಸರ್ವ ಸರ್ಮರ್ಥ- ಆದ್ದರಿಂದ ಜ್ಞಾನಾನಂದ\nಸ್ವರೂಪ ಭಗವಂತ 'ಉ'. ಓಂಕಾರದ ಮೂರನೇ ಅಕ್ಷರ 'ಮ'. \"ಮ' ಎಂದರೆ ಜ್ಞಾನಸ್ವರೂಪ. ಇದನ್ನು ಪ್ರಣವದ\n\"ವ' ಅಕ್ಷರ ವಿವರಿಸುತ್ತದೆ. “ವ' ಎಂದರೆ ಜ್ಞಾನ-ಅದು ಸರ್ವಜ್ಞ ಎನ್ನುವ ಅರ್ಥವನ್ನು ಕೊಡುತ್ತದೆ. ಹೀಗೆ ಓಂಕಾರದ\nಒಂದು ಮುಖವನ್ನು 'ಪ್ರಣವಃ' ವಿವರಿಸುತ್ತದೆ.\n\nಉಪನಿಷತ್ತಿನಲ್ಲಿ ಹೇಳುವಂತೆ “ನೇತಿ ನೇತಿ ಆತ್ಮಾ ಅಗ್ರಹ್ಯಃ ನ ಹಿ ಗ್ರಹ್ಯತೆ”-ಅಂದರೆ ಭಗವಂತನನ್ನು ಮೊದಲು\nತಿಳಿಯುವುದೇನೆಂದರೆ. “ಭಗವಂತ ಪೂರ್ಣವಾಗಿ ತಿಳಿಯಲಿಕ್ಕಾಗುವ ವಸ್ತುವಲ್ಲ” ಎಂದು! : ಅವನನ್ನು\nಪೂರ್ಣವಾಗಿ ತಿಳಿಯುವುದು ಅಸಾಧ್ಯ ಎಂದು ತಿಳಿಯುವುದೇ ಮೊದಲು ನಾವು ಭಗವಂತನ ಬಗ್ಗೆ\nತಿಳಿಯಬೇಕಾದ ವಿಷಯ. ಇದನ್ನು ಓಂಕಾರ ವಿವರಿಸುತ್ತದೆ. ಇಲ್ಲಿ 'ಅ' ಎಂದರೆ ಅಲ್ಲ ಅಥವಾ ಇಲ್ಲ . ಭಗವಂತ\nಅಲ್ಲ, ಭಗವಂತ ಇಲ್ಲ! ಅಂದರೆ ಭಗವಂತ ಪೂರ್ಣವಾಗಿ ತಿಳಿಯಲು ಆಗುವ ಸಂಗತಿಯಲ್ಲ; ಏಕೆಂದರೆ ನಾವು\nತಿಳಿದಿರುವ ವಸ್ತುವಿನಲ್ಲಿ ಏನಿದೆಯೋ ಅದು ಅವನಲ್ಲಿಲ್ಲ. ನಮಗೆ ತ್ರಿಗುಣಾತ್ಮಕ ಪ್ರಪಂಚದ ಪರಿಚಯ ಮಾತ್ರ\nಇದೆ, ಆದರೆ ಭಗವಂತ ತ್ರಿಗುಣಾತೀತ. ತ್ರಿಗುಣಾತ್ಮಕವಾದ ನಮ್ಮ ಮನಸ್ಸು ತ್ರಿಗುಹಾತೀತವನ್ನು\nಗ್ರಹಿಸಲಾರದು. ಭಗವಂತನಲ್ಲಿ ಯಾವ ದೋಷವೂ ಇಲ್ಲ. ಆತ ಸರ್ವಗುಣಪೂರ್ಣ. ಭಗವಂತ ನಮ್ಮ\nನಿಲುವಿನಿಂದ ಅತೀತ.\n\nಭಗವಂತ 'ಉ'. ನಮ್ಮ ಮನಸ್ಸು ಏರಬಹುದಾದ ಎತ್ತರಕ್ಕೆಂತಲೂ ಉನ್ನತವಾಗಿರುವ ವಸ್ತು. ನಮ್ಮ ಮನಸ್ಸು ಆ\nಎತ್ತರಕ್ಕೆ ಏರಲು ಸಾಧ್ಯವಿಲ್ಲ. ಆದರೂ ಆತ \"ಮ”-ಅಂದರೆ ಆತನನ್ನು ತಿಳಿಯಬಹುದು! ಅಂದರೆ ಭಗವಂತ\n\nಸಮುದ್ರದಂತೆ. ನಾವು ಪೂರ್ಣ ಸಮುದ್ರವನ್ನು ತಂದು ನಮ್ಮ ಮನೆಯ ಪಾತ್ರೆಯಲ್ಲಿ ತುಂಬಿಡಲು ಸಾಧ್ಯವಿಲ್ಲ.\nಆದರೆ ನಮ್ಮ ಪಾತ್ರೆಯಲ್ಲಿ ಎಷ್ಟು ತುಂಬಬಹುದೋ ಅಷ್ಟು ನೀರನ್ನು ತುಂಬಿ ತರಬಹುದು. ಅದೇ ರೀತಿ\nಭಗವಂತನನ್ನು ನಾವು ಪೂರ್ಣ ಗ್ರಹಿಸಲು ಅಸಾಧ್ಯ, ಆದರೆ ನಮ್ಮ ನಮ್ಮ ಸಾಮರ್ಥ್ಯಕ್ಕನುಗುಣವಾಗಿ ಆತನನ್ನು\nತಿಳಿಯಬಹುದು. ಓಂಕಾರ “ಭಗವಂತನನ್ನು ಪೂರ್ಣ ತಿಳಿಯಲು ಅಸಾಧ್ಯ, ಆದರೆ ನಿಮ್ಮ ನಿಮ್ಮ ಯೋಗ್ಯತೆಗೆ\nತಕ್ಕಂತೆ ಭಗವಂತನನ್ನು ತಿಳಿಯಲು ಪ್ರಯತ್ನಿಸಿ” ಎನ್ನುವ ವೇದದ ಸಂದೇಶವನ್ನು ನಮಗೆ ತಿಳಿಸುತ್ತದೆ.\nಭಗವಂತನನ್ನು ಯಾವ ರೀತಿ ಅನುಸಂಧಾನ ಮಾಡಬೇಕು ಎನ್ನುವುದನ್ನು ಓಂಕಾರ ತಿಳಿಸುತ್ತದೆ. ಭಗವಂತ “ಅ'\nಅಂದರೆ ಆತ ಅತೀತ-ಯಾವುದು ಸೃಷ್ಟಿಯ ಪೂರ್ವದಲ್ಲಿ ಇತ್ತೋ ಅದು 'ಅ'. ನಾವು ಉತ್ಪ ನ್ನ ರಾದ ನಂತರ\nಇರುವ ಭಗವಂತ \"ಉ'; ಎಲ್ಲವೂ ನಾಶವಾದ ಮೇಲೆ ಇರುವ ಭಗವಂತ \"ಮ'. ತ್ರಿಕಾಲದಲ್ಲಿ ಏಕರೂಪವಾಗಿರುವ\nಭಗವಂತ ಓಂ.\n\nಭಗವಂತ 'ಅ' ಅಂದರೆ ಭೂಃ (ಭೂಮಿ); ಆತ \"ಉ' -ಭೂಮಿಯ ಉಪರಿಯಲ್ಲಿರುವ ಅಂತರಿಕ್ಷ(ಭುವಃ); ಆತ \"ಮ'\nಅಂದರೆ ಜ್ಞಾನಪ್ರದವಾದ ಸ್ವರ್ಗ(ಸ್ವಃ). ಮೂರು ಲೋಕವನ್ನು ನಿಯಮಿಸುವ ಶಕ್ತಿ ಭಗವಂತ ಓಂ.\n\nನಮ್ಮ ಮೂರು ಅವಸ್ಥೆಗಳಾದ “ಅ'-ಎಚ್ಚರ, \"ಉ'-ಕನಸು; 'ಮ”-ನಿದ್ದೆಯನ್ನು ನಿಯಂತ್ರಿಸುವ ಅನಂತ ಶಕ್ತಿ\nಭಗವಂತ ಓಂ.\n\nಹೀಗೆ ಸಮಸ್ತ ವೈದಿಕ ವಾಜ್ಮಯ ಯಾವ ಗುಣವನ್ನು ಭಗವಂತನಲ್ಲಿ ಉಪಾಸನೆ ಮಾಡಬೇಕೆಂದು\nಹೇಳುತ್ತದೋ; ಸರ್ವನಾಮ ವಾಚ್ಯನಾದ ಭಗವಂತನಲ್ಲಿ ಸರ್ವನಾಮಗಳು ಯಾವ ಗುಣವನ್ನು ಹೇಳುತ್ತವೋ-\nಅವೆಲ್ಲವನ್ನೂ ಸಂಗ್ರಹ ಮಾಡಿ ಭಟ್ಟಿ ಇಳಿಸಿ ಸಾರಯುಕ್ತವಾಗಿ ಹೇಳತಕ್ಕಂತಹ ಬೀಜಾಕ್ಷರ ಓಂಕಾರ. ಇದು\nಭಗವಂತನ ಸ್ತೋತ್ರದಲ್ಲೇ ಅತ್ಯಂತ ಶ್ರೇಷ್ಠವಾದ ಸ್ತುತಿ. ಭಗವಂತನನ್ನಲ್ಲದೆ ಇನ್ಯಾರನ್ನೂ 'ಓಂ' ಎಂದು\nಕರೆಯಲು ಅಸಾಧ್ಯ. [ಈ ಕಾರಣಕ್ಕಾಗಿ ಸಾಮಾನ್ಯವಾಗಿ 'ಓಂ' ನ್ನು ಯಾರೂ ತಮ್ಮ ಹೆಸರಾಗಿ ಬಳಸುವುದಿಲ್ಲ,\nಬಳಸಬಾರದು].\n\nಓಂಕಾರದ ಹಿಂದಿರುವ ಎಲ್ಲಾ ಅರ್ಥಾನುಸಂಧಾನದೊಂದಿಗೆ ಜಪ ಮಾಡಿದರೆ ಅದು ಅತ್ಯಂತ ಪರಿಣಾಮಕಾರಿ.\nಸಾಮಾನ್ಯವಾಗಿ ಸನ್ಯಾಸಿಗಳು ಓಂಕಾರ ಜಪವನ್ನು ಮಾಡುತ್ತಾರೆ. ಗ್ರಹಸ್ಥನಾದವನು ನಿರಂತರ ಓಂಕಾರ ಜಪ\nಮಾಡುವುದು ಅಷ್ಟು ಸೂಕ್ತವಲ್ಲ. ಗರಿಷ್ಠ ಹತ್ತುಬಾರಿ ಮಾಡಬಹುದು. ಸಂಸಾರ ಜೀವನ ನಡೆಸುವ ಹೆಂಗಸರು\nಓಂಕಾರ ಜಪ ಮಾಡದಿರುವುದು ಒಳ್ಳೆಯದು. ಏಕೆಂದರೆ ಓಂಕಾರವನ್ನು ಪೂರ್ಣ ತೊಡಗಿಸಿಕೊಂಡು,\nಅರ್ಥಾನುಸಂಧಾನದಿಂದ ಜಪ ಮಾಡುವುದರಿಂದ ಅದು ಮನಸ್ಸಿನ ಮೇಲೆ ಮಹತ್ತರವಾದ ಪರಿಣಾಮವನ್ನು\nಬೀರುತ್ತದೆ. ಇದು ಒಂದು ರೀತಿಯ ಧ್ಯಾನವಿದ್ದಂತೆ. ಇದರಿಂದ ಮನಸ್ಸು ಮಗ್ನವಾಗಿ, ಸಾಂಸಾರಿಕ ಜೀವನದಲ್ಲಿ\nವೈರಾಗ್ಯ ಬರುವ ಅಪಾಯವಿದೆ. ಆದರೆ ಸನ್ಯಾಸಿಗೆ ಈ ರೀತಿಯ ಯಾವ ಸಮಸ್ಯೆಯೂ ಇಲ್ಲ. ಆತ ತನ್ನ ದೇಹ\nತಡೆದುಕೊಳ್ಳುವಷ್ಟು(೧೨,೦೦೦) ಬಾರಿ ಓಂಕಾರ ಜಪ ಮಾಡಬಹುದು.\n",
  "7.9": "ಪುಣ್ಯಃ ಗಂಧಃ ಪೃಥಿವ್ಯಾಮ್‌ ಚ ತೇಜಃ ಚ ಅಸ್ಮಿ ವಿಭಾವಸೌ |\n\nಜೀವನಮ್‌ ಸರ್ವ ಭೂತೇಷು ತಪಃ ಚ ಅಸ್ಮಿ ತಪಸ್ವಿಷು -ಮಣ್ಣಿನಲ್ಲಿ ನರುಗಂಪೂ ನನ್ನಿಂದ. [ಪವಿತ್ರನಾಗಿ\nಮಣ್ಣಿನಲ್ಲಿದ್ದು ಗಂಧದ ಅರಿವು ನೀಡುವುದರಿಂದ “ಪುಣ್ಯ' ಮತ್ತು 'ಗಂಧ' ನಾಮಕ]. ಬೆಂಕಿಯಲ್ಲಿ ಸುಡುವ ಶಕ್ತಿಯೂ\nನನ್ನಿಂದ.[ಬೆಂಕಿಯಲ್ಲಿದ್ದು ಸುಡುವವನಾದ್ದರಿಂದ “ತೇಜಸ್‌' ನಾಮಕ]. ಎಲ್ಲಾ ಜೀವಿಗಳಲ್ಲಿ ಬದುಕು ನನ್ನಿಂದ.\n[ಎಲ್ಲಾ ಜೀವಿಗಳಲ್ಲಿದ್ದು ಬದುಕಿಸುವುದರಿಂದ 'ಜೀವನ'ನಾಮಕ]. ತಾಪಸರಲ್ಲಿ ತಪಃಶಕ್ತಿ ನನ್ನಿಂದ.\n[ತಾಪಸರಲ್ಲಿದ್ದು ತಪದ ಶಕ್ತಿ ನೀಡುವುದರಿಂದ “ತಪಸ್‌' ನಾಮಕ].\n\nಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಪುಣ್ಯೋ ಗಂಧಃ ಪೃಥಿವ್ಯಾಂ- ನೆಲದಲ್ಲಿ ಸುಗಂಧ ನನ್ನಿಂದ” ಎಂದು. ಯಾವ ಗಂಧ ನಮ್ಮ\nಮೂಗಿಗೆ ಅಹ್ಲಾದವನ್ನು ಕೊಡುತ್ತದೋ ಅದು 'ಪುಣ್ಯಗಂಧ'. ಇಲ್ಲಿ ಪುಣ್ಯ ಎಂದರೆ ಪವಿತ್ರ ಅಥವಾ ಸುಂದರ\nಎನ್ನುವ ಅರ್ಥವನ್ನು ಕೊಡುತ್ತದೆ. ಈ ಭೂಮಿಯಲ್ಲಿ, ಭೂಮಿಯಮೇಲೆ ಹುಟ್ಟುವ ಪ್ರತಿಯೊಂದು ವಸ್ತುವಿಗೆ\nಸುಗಂಧ ಕೊಟ್ಟವನು 'ಪುಣ್ಯ' ನಾಮಕ ಭಗವಂತ. ಆತ ತನ್ನ ವಿಶೇಷ ರೂಪದಲ್ಲಿ 'ಗಂಧ' ನಾಮಕನಾಗಿ ಆ\nವಸ್ತುವಿನಲ್ಲಿ ಸೇರಿಕೊಂಡಿರುವುದರಿಂದ ವಸ್ತುವಿಗೆ ಒಂದು ವಿಶೇಷ ಗುಣ ಬಂತು. ಈ ಭೂಮಿಯಲ್ಲಿ ಹುಟ್ಟುವ\nಗಿಡಬಳ್ಳಿಗಳು , ವನಸ್ಪತಿಗಳು, ಅನಂತ ಬಗೆಯ ಹೂಗಳು, ಹಣ್ಣುಗಳು, ಎಲ್ಲವುದರಲ್ಲೂ ಆ ವಿವಿಧತೆ-ಕಂಪು ಆ\nಭಗವಂತನಿಂದ. ಭೂಮಿಯ ಅಭಿಮಾನಿ ದೇವತೇಪ್ರಥ್ವೀ ದೇವತೆ)ಯೊಳಗಿದ್ದು, ಪ್ರಥ್ವಿಯಲ್ಲಿ ಗಂಧ ಶಬ್ದ\nವಾಚ್ಯನಾಗಿ ಗಂಧದಲ್ಲಿ ನೆಲೆಸಿದ್ದಾನೆ ಭಗವಂತ. ನೆಲ ಎಲ್ಲವುದಕ್ಕೂ ನೆಲೆ, ಭಗವಂತ ನೆಲದಲ್ಲಿ ನೆಲೆ\nನಿಂತುದರಿಂದ ನೆಲದಲ್ಲಿ ಮೂಡಿಬರುವ ಪ್ರತಿಯೊಂದು ವಸ್ತುವೂ ಕೂಡಾ ಒಂದೊಂದು ಬಗೆಯ ವಿಶಿಷ್ಟ\nಸುಗಂಧವನ್ನು ಹೊತ್ತು ತರುತ್ತದೆ. ಹೀಗೆ ಭಗವಂತ ತನ್ನ ಸೃಷ್ಟಿಯಲ್ಲಿ ಸೌಂದರ್ಯಭರಿತ ವಿಶಿಷ್ಟ ಗಂಧದ\nಪ್ರಪಂಚವನ್ನೇ ನಮ್ಮ ಮೂಗಿನ ಮುಂದೆ ತೆರೆದಿಟ್ಟ.\n\nಹಿಮಾಲಯದ “ಹೂಗಳ ಕಣಿವೆಯಲ್ಲಿ(Valley of Flowers) ಅನಂತ ಪ್ರಕಾರದ ಹೂವಿನ ಪ್ರಪಂಚವಿದೆ. ಒಂದು\nಹೂವಿನ ಪರಿಮಳ ಇನ್ನೊಂದಕ್ಕಿಂತ ಭಿನ್ನ. ಎಲ್ಲಾ ಗಿಡಗಳೂ ಕೂಡಾ ಒಂದೇ ಮಣ್ಣಿನಿಂದ ಬೆಳೆಯುವುದಾದರೂ\nಕೂಡಾ, ಭಗವಂತ ಒಂದೊಂದು ಗಿಡದಲ್ಲಿ ಒಂದೊಂದು ವಿಶಿಷ್ಟಗುಣವನ್ನು (exclusive quality) ತುಂಬಿದ.\nಕೆಲವು ಹೂವಿನಲ್ಲಿ ನಾವು ಗುರುತಿಸಲು ಸಾಧ್ಯವಾಗುವ ಸುವಾಸನೆ ಇರುವುದಿಲ್ಲ. ಸಾಮಾನ್ಯವಾಗಿ ಇಂತಹ\nಹೂವನ್ನು ದೇವರಿಗೆ ಅರ್ಪಿಸುವುದಿಲ್ಲ. ಇದಕ್ಕೆ ಕಾರಣ ದೇವರ ಪೂಜೆಯ ಪ್ರತಿಯೊಂದು ಕ್ರಿಯೆಯೂ ಕೂಡಾ\nಆನಂದಮಯವಾಗಿರಬೇಕು ಎನ್ನುವ ಅನುಸಂಧಾನ. ಪೂಜೆ ಮಾಡುವಾಗ ಆ ಹೂವಿನ ಅಹ್ಲಾದಕರ ಕಂಪು\nಮೂಗಿಗೆ ಬಡಿದಾಗ ನಮಗೆ 'ಪುಣ್ಯ' ಅಥವಾ “ಗಂಧ' ನಾಮಕ ಭಗವಂತನ ಅರಿವು ಮೂಡಬೇಕು.\n\nನೀರು, ಸೂರ್ಯ, ಚಂದ್ರ, ಆಕಾಶ ಹಾಗೂ ಭೂಮಿಯ ಬಗ್ಗೆ ಹೇಳಿದ ಭಗವಂತ ಮುಂದುವರಿದು ಭೂಮಿಯಲ್ಲಿ\nಭಗವಂತನ ಆರಾಧನೆಗೆ ಮುಖ್ಯ ಪ್ರತಿಷ್ಠಾನವಾದ ಅಗ್ನಿ(ವಿಭಾವಸು)ಯಲ್ಲಿ ತನ್ನ ವಿಭೂತಿ ವಿಜ್ಞಾನವನ್ನು\nವಿವರಿಸುತ್ತಾನೆ. ವಿಭಾವಸು ಭೂಮಿಯಲ್ಲಿ ಅಗ್ನಿಯ ಅಭಿಮಾನಿ ದೇವತೆ. ಈತ ಅಷ್ಟವಸುಗಳಲ್ಲಿ[ದ್ರೋಣ, ಪ್ರಾಣ,\nಧ್ರುವ, ಅರ್ಕ, ಅಗ್ನಿ(ವಿಭಾವಸು), ದೋಷ, ವಸ್ತು, ದ್ಯುವಸು1 ಐದನೇಯವ. ಈತನಿಗೆ ಅನೇಕ ನಾಮಗಳು:\n\nವೈಶ್ವಾನರ, ವಹ್ನಿ, ಜಾತವೇದ, ಹುತಾಶನ, ಪಾವಕ, ಅನಲ, ದಹನ ಇತ್ಯಾದಿ. ನಮಗೆ ಭೂಮಿಯಲ್ಲಿ ಅಗ್ನಿ\nಎನ್ನುವುದು ಬಹಳ ಮುಖ್ಯವಾದ ಭಗವಂತನ ಪ್ರತೀಕ. ವೇದ ಪ್ರಾರಂಭವಾಗುವುದೂ ಕೂಡಾ “ಅಗ್ನಿ ಮೀ”ಳೇ\nಪುರೋಹಿತಂ ಯಜ್ಞಸ್ಯ ದೇವಮೃತ್ವಿಜಂ” ಎಂದು ಅಗ್ನಿ ನಾಮದಿಂದ. ನೆಲದಲ್ಲಿ ಭಗವಂತನನ್ನು ಪೂಜಿಸಲು\nಅಗ್ನಿಗಿಂತ ಉತ್ತಮ ಪ್ರತೀಕ ಇನ್ನೊಂದಿಲ್ಲ. ಅಗ್ನಿ ಬೆಳಕಿನ ರೂಪ, ಅಗ್ನಿ ಪವಿತ್ರ. ಕೊಟ್ಟದ್ದನ್ನು ಸ್ವೀಕರಿಸುವ\nಭಗವಂತನ ಏಕೈಕ ಪ್ರತೀಕ ಅಗ್ನಿ. ಇಲ್ಲಿ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ತೇಜಶ್ವಾಸ್ಮಿ ವಿಭಾವಸೌ” ಎಂದು. ಅಂದರೆ\n“ಇಂತಹ ಅಗ್ನಿದೇವತೆಯೊಳಗೆ ದಾಹಕ, ಪಾಚಕ, ಪ್ರಕಾಶಕ ಶಕ್ತಿಯಾಗಿ, ತೇಜಸ್ಸಾಗಿ-ನಾನಿದ್ದೇನೆ” ಎಂದು.\nಹೊರ ಪ್ರಪಂಚದಲ್ಲಿ ಉರಿಯುವ ಬೆಂಕಿಯಲ್ಲಿ ಭಗವಂತನಿದ್ದರೆ ನಮ್ಮ ನಾಲಿಗೆಯಲ್ಲಿ ಕುಳಿತ ಅಗ್ನಿ ನಾಮಕ\nಭಗವಂತ(ಅಗ್ನಿನಾರಾಯಣ) ನಮಗೆ ಮಾತು ಎನ್ನುವ ಬೆಳಕನ್ನು ಕೊಟ್ಟು ನಮ್ಮೊಳಗೆ ವಾಜ್ಮಯನಾಗಿರುವ\nದೊಡ್ಡ ಬೆಳಕು. ಹಾಗೇ ವೈಶ್ವಾನರನಾಗಿ ನಮ್ಮ ಪಚನ ಕ್ರಿಯೆಯನ್ನು ನಿಯಂತ್ರಿಸುವವನೂ ಆತನೇ. [ಈ ಬಗ್ಗೆ\nಹೆಚ್ಚಿನ ವಿವರವನ್ನು ಮುಂದೆ ಅಧ್ಯಾಯ ಹತ್ತರಲ್ಲಿ ಕಾಣಬಹುದು].\n\nಮುಂದುವರಿದು ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ವಾಯುವಿನಲ್ಲಿ ತುಂಬಿ ಪ್ರತಿಯೊಂದು ಜೀವಜಾತದ ಉಸಿರಾಗಿ, ಜೀವಕ್ಕೆ\nಉಸಿರಿನ ಶಕ್ತಿ ಕೊಟ್ಟು ನಾನು ನಿಂತಿದ್ದೇನೆ” ಎಂದು. ಜೀವನಪ್ರದ ಅಭಿಮಾನಿ ದೇವತೆ “ಪ್ರಾಣದೇವರು”. ನಾವು\nಇತರ ಇಂದ್ರಿಯ ಕೆಲಸ ಮಾಡದೇ ಇದ್ದರೆ ಬದುಕಬಹುದು. ಆದರೆ ಪ್ರಾಣಶಕ್ತಿ(ಉಸಿರಾಟ) ಕೆಲಸ ಮಾಡದೇ\nಇದ್ದರೆ ಬದುಕಲು ಸಾಧ್ಯವಿಲ್ಲ. ನಿದ್ದೆಯಲ್ಲಿ ನಮ್ಮ ಇತರ ತತ್ತ್ವಾಭಿಮಾನಿ ದೇವತೆಗಳು ನಿದ್ರಿಸಬಹುದು. ಆದರೆ\nಪ್ರಾಣದೇವರು ನಿದ್ರಿಸಿದರೆ ನಾವು ಪುನಃ ಎಚ್ಚರವಾಗಲು ಸಾಧ್ಯವಿಲ್ಲ! ಭಗವಂತ ಅಹೋರಾತ್ರಿ\nಜೀವನಪ್ರದನಾದ ಪ್ರಾಣನೊಳಗೆ 'ಪ್ರಾಣ'ನಾಗಿ ನಿಂತು ನಮ್ಮನ್ನು ಬದುಕಿಸುತ್ತಾನೆ.\n\nಪಂಚಭೂತಗಳ ಬಗ್ಗೆ ವಿವರಿಸಿದ ಕೃಷ್ಣ ಮುಂದೆ ಮಾನಸ ಪ್ರಪಂಚದ ಬಗ್ಗೆ ವಿವರಿಸುತ್ತಾನೆ. ಮನೋಮಯ\nಪ್ರಪಂಚದಲ್ಲಿ ಬದುಕುವವರು ತಪಸ್ವಿಗಳು(ತಪ-ಆಲೋಚನೆ).ಮನಸ್ಸಿನ ಆಳವಾದ ಚಿಂತನೆಗೆ\nತಪಸ್ಸು ಎನ್ನುತ್ತಾರೆ. ಇದರ ಅಭಿಮಾನಿ ಶಿವ. ನಾವು ಮಾತನಾಡುವುದು-ನಮ್ಮ ಮನಸ್ಸಿಗೆ ಹೊಳೆಯುವ\nವಿಚಾರಗಳನ್ನು. ನಮ್ಮ ಮನಸ್ಸಿಗೆ ಅಂತಹ ಅದ್ಭುತ ಆಲೋಚನಾಶಕ್ತಿ ಕೊಟ್ಟು, ಮನೋಮಯಕೋಶದಲ್ಲಿ\nನಿಂತು ನಮಗೆ ಆನಂದದ ಅನುಭವವನ್ನು ಕೊಡುವವ ಆ ಭಗವಂತ. ಹೀಗೆ ಪಂಚಭೂತಗಳಲ್ಲಿ;\nಅನ್ನಮಯಕೋಶದಿಂದ ಹಿಡಿದು ಆನಂದಮಯಕೋಶದ ತನಕ ಹೇಗೆ ಭಗವಂತ ವಿಭೂತಿರೂಪದಲ್ಲಿ\nನಿಂತಿದ್ದಾನೆ ಎನ್ನುವ ಅದ್ಭು ತ ಅಧ್ಯಾತ್ಮ ವಿಜ್ಞಾನ(divine science)ವನ್ನು ಈ ಎರಡು ಶ್ಲೋಕ(ಲ ಮತ್ತು ೯)ದಲ್ಲಿ\nಕೃಷ್ಣ ವಿವರಿಸಿದ.\n\nಕೃಷ್ಣ ಪಿಂಡಾಂಡ-ಬ್ರಹ್ಮಾಂಡದಲ್ಲಿ ನಿಂತು ಹೇಗೆ ವಿಭೂತಿಯಾಗಿ ಬೇರೆ ಬೇರೆ ವಸ್ತುವಿನಲ್ಲಿ ವಿಶಿಷ್ಟ ಶಕ್ತಿಯನ್ನು\nತುಂಬುತ್ತಾನೆ ಎನ್ನುವ ಮಾತಿನ ಸಂಕ್ಷಿಪ್ತ ಉಪಾಸನೆಯನ್ನು ನೋಡಿದೆವು. ಈ ವಿಭೂತಿಯ ವಿಸ್ತಾರ ಮುಂದಿನ\nಅಧ್ಯಾಯದಲ್ಲಿ ಪುನಃ ಬರುತ್ತದೆ. ಇಲ್ಲಿ ಕೃಷ್ಣ ಅದನ್ನು ಕ್ರೋಡೀಕರಣ ಮಾಡಿ ಸಮಷ್ಟಿಯಾಗಿ ವಿಭೂತಿಯ\nಅನುಸಂಧಾನ ಹೇಗಿರಬೇಕು ಎಂದು ವಿವರಿಸಿದ್ದಾನೆ.",
  "7.10": "ಬೀಜಮ್‌ ಮಾಮ್‌ ಸರ್ವಭೂತಾನಾಮ್‌ ವಿದ್ಧಿ ಪಾರ್ಥ ಸನಾತನಮ್‌ ।\n\nಬುದ್ಧಿಃ ಬುದ್ಧಿಮತಾಮ್‌ ಅಸ್ಮಿ ತೇಜಃ ತೇಜಸ್ವಿನಾಮ್‌ ಅಹಮ್‌- ಓ ಪಾರ್ಥಾ, ಎಲ್ಲಾ ಜೀವಿಗಳ ಅಳಿವಿರದ ಬೀಜ\n[ಸ್ವಭಾವದ ಅಭಿವ್ಯಕ್ತಿಗೆ ಕಾರಣನಾಗಿ 'ಬೀಜ' ನಾಮಕ] ನಾನೆಂದು ತಿಳಿ. ತಿಳಿದವರ ತಿಳಿವು ನನ್ನಿಂದ.\n[ತಿಳಿದವರೊಳಗಿದ್ದು ತಿಳಿವು ನೀಡುವುದರಿಂದ 'ಬುದ್ಧಿ'ನಾಮಕ ]. ಪರಾಕ್ರಮಿಗಳ ಸೋಲರಿಯದ ಶಕ್ತಿ ನನ್ನಿಂದ.\n[ಪರಾಕ್ರಮಿಗಳೊಳಗಿದ್ದು ಸೋಲರಿಯದ ಶಕ್ತಿ ನೀಡುವುದರಿಂದ 'ತೇಜಸ್‌' ನಾಮಕ].\n\nಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಬೀಜಮ್‌ ಮಾಮ್‌ ಸರ್ವಭೂತಾನಾಮ್‌” ಎಂದು. ಅಂದರೆ “ಎಲ್ಲಾ ಜೀವಗಳ ಬೀಜ'\nನಾನು ಎಂದು. ಬೀಜ ಎಂದಾಗ ನಮಗೆ ಸಾಮಾನ್ಯವಾಗಿ ನೆನಪಿಗೆ ಬರುವುದು ಮರಗಿಡದ ಬೀಜ. ಈ\nಬೀಜವನ್ನು ಬಿತ್ತಿದಾಗ ಅದು ಮರವಾಗಿ ಬೆಳೆಯುತ್ತದೆ. ಅಂದರೆ ಮರಕ್ಕೆ ಬೀಜ ಉಪಧಾನ ಕಾರಣ. ಹಾಗೇ\nಭಗವಂತ ಕೂಡಾ ಈ ಜಗತ್ತಿಗೆ ಉಪಧಾನ ಕಾರಣವೆ? ಇದು ನಮ್ಮ ಮುಂದೆ ಬರುವ ಮೊದಲ ಪ್ರಶ್ನೆ. ಇದನ್ನು\nತಿಳಿಯಬೇಕಾದರೆ ಮೊದಲು ನಾವು “'ಬೀಜ' ಅನ್ನು ವ ಪದದ ಆಧ್ಯಾತ್ಮಿಕ ಅರ್ಥವಿಶೇಷವನ್ನು (ಆ(etymological meaning) ಅರಿಯಬೇಕು. ಬೀಜ ಎನ್ನುವುದು 'ಅಂಜು' ಧಾತುವಿನಿಂದ ಬಂದಿರುವುದು. ಇಲ್ಲಿ \"ವಿ' ವಿಸರ್ಗ.\nಯಾವುದು ವ್ಯಂಜನ (ವ್ಯಂಜನಾತ್‌) ಅದು ಅಭಿವ್ಯಂಜನ. ಅಂದರೆ ಯಾರಿಂದ ಅಭಿವ್ಯಕ್ತವಾಯಿತೋ ಅದು\nಬೀಜ. ಯಾವುದು(ಮೂಲವಸ್ರು) ಇದ್ದೂ ಕಾಣಿಸುತ್ತಿರಲಿಲ್ಲವೋ ಅದಕ್ಕೆ ಕಾಣುವಂತಹ ಆಕಾರಕೊಟ್ಟವನು ಆ\nಭಗವಂತ. ಅಂದರೆ ಸೂಕ್ಷ್ಮ ರೂಪದಲ್ಲಿ ತುಂಬಿದ್ದ ಈ ಅವ್ಯಕ್ತ ಪ್ರಪಂಚಕ್ಕೆ ವ್ಯಕ್ತವಾದ ರೂಪ ಕೊಟ್ಟವ. ಆದ್ದರಿಂದ\nಇಡೀ ಪ್ರಪಂಚದಲ್ಲಿರುವ ಜೀವಜಾತಕ್ಕೆ ಅಭಿವ್ಯಕ್ತವನ್ನು ಕೊಟ್ಟವನು ಯಾರೋ ಅವನು ಸರ್ವಭೂತಗಳಿಗೆ ಬೀಜ.\nಈ ಜಗತ್ತಿಗೆ ತಂದೆಯೂ ತಾಯಿಯೂ ಆದ ಆ ಭಗವಂತ ಬೀಜ. ಪ್ರಳಯ ಕಾಲದಲ್ಲಿ ಕಣ್ಣಿಗೆ ಕಾಣದ(ಅವ್ಯಕ್ತ),\nಸೂಕ್ಷ್ಮರೂಪದಲ್ಲಿ ಇದ್ದ ಈ ಪ್ರಪಂಚಕ್ಕೆ-ವ್ಯಕ್ತವಾದ ರೂಪವನ್ನು ಕೊಟ್ಟವ “ಸರ್ವಭೂತಾನಾಂ ಬೀಜ'.\n\nಜಗತ್ತಿನ ಸಮಸ್ತ ಜೀವಜಾತಕ್ಕೆ ಅಂದರೆ. ಚತುರ್ಮುಖ-ಪ್ರಾಣ-ಗರುಡ-ಶೇಷ-ರುದ್ರ-ಇಂದ್ರ-ಕಾಮ-ಸರ್ವ\nದೇವತೆಗಳು, ಮಾನವರು, ವನಸ್ಪತಿಗಳು, ಇತ್ಯಾದಿ. ಹೀಗೆ ಸಮಸ್ತ ಜೀವಕೋಟಿಗೆ ದೇಹಕೊಟ್ಟು, ಆಕಾರ\nಕೊಟ್ಟು, ಅಭಿವ್ಯಕ್ತಿಕೊಟ್ಟು, ಇಡೀ ಜೀವಜಾತದ ಹಿಂದೆ ತಂದೆಯಾಗಿ ನಿಂತವ ಆ ಭಗವಂತ. ಈ ಪ್ರಪಂಚದಲ್ಲಿ\nಯಾವ-ಯಾವ ಜೀವಜಾತವಿದೆ, ಆ ಜೀವಜಾತದಲ್ಲಿರುವ ವಿಶೇಷ ಗುಣಧರ್ಮದ(exclusive quality) ಹಿಂದೆ\nಕಾರಣ ಪುರುಷನಾಗಿ, ವ್ಯಕ್ತಿತ್ವ ವಿಕಸನಕ್ಕೆ (ಅಭಿವ್ಯಕ್ತಿಗೆದ ಮೂಲಕಾರಣನಾಗಿ ಆ ಭಗವಂತ ನಿಂತಿದ್ದಾನೆ.\nನಮಗಿರುವ ಬೀಜದ ಇನ್ನೊಂದು ಕಲ್ಪನೆ -ಅದು ಮರವಾಗಿ ಬೆಳೆದಾಗ ತನ್ನ ಆಕಾರವನ್ನು ಕಳೆದುಕೊಳ್ಳುತ್ತದೆ\nಎನ್ನುವುದು. ಆದರೆ ಭಗವಂತ “ಸನಾತನ”. ಇಲ್ಲಿ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ನಾನು ನಾನಾಗಿಯೇ ಇದ್ದು ಪ್ರಪಂಚಕ್ಕೆ\nಆಕಾರ ಕೊಡುತ್ತೇನೆ” ಎಂದು. ಅಂದರೆ ಭಗವಂತ ಎಂದೂ ಬದಲಾಗುವುದಿಲ್ಲ-ಆದರೆ ಪ್ರಪಂಚ ಬದಲಾಗುತ್ತದೆ.\nಭಗವಂತ ಪ್ರಪಂಚಕ್ಕೆ ಬೇರೆ ಬೇರೆ ಆಕಾರದ ಅಭಿವ್ಯಕ್ತ ಕೊಡುತ್ತಾನೆ. ಹೊಸ ಶಕ್ತಿ ಕೊಡುತ್ತಾನೆ. ಇದರಿಂದ ಅದು\nಬದಲಾಗುತ್ತಾ, ಹೊಸ ರೂಪ ಪಡೆಯುತ್ತಾ ಇರುತ್ತದೆ. ಇದಕ್ಕೆ ಕಾರಣಪುರುಷನಾದ ಭಗವಂತ ಮಾತ್ರ ಎಲ್ಲಾ\n\nಕಾಲದಲ್ಲೂ ಏಕರೂಪದಲ್ಲಿರುತ್ತಾನೆ. ಹೀಗೆ ಭಗವಂತ ಸಮಸ್ತ ಭೂತಗಳಿಗೆ(ಜಡ, ಚೇತನ, ಮುಕ್ತರು) ಬೀಜ\nಮತ್ತು ಆತ ಸನಾತನ.\n\nಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ಬುದ್ಧಿರ್ಬುದ್ಧಿಮತಾಮಸ್ಮಿ ತೇಜಸ್ತೇಜಸ್ವಿನಾಮಹಮ್‌” ಎಂದು. ಅಂದರೆ “ಬುದ್ಧಿವಂತರ\nಬುದ್ಧಿಮತ್ತೆ ಏನಿದೆ ಅದು ನನ್ನ ಕೊಡುಗೆ; ಹಾಗೇ ತೇಜಸ್ವಿಗಳಿಗೆ ತೇಜಸ್ವಿ ನಾನು”. ಜ್ಞಾನಪ್ರದ ಜೀವರಲ್ಲಿ\nಜ್ಞಾನಶಕ್ತಿಯನ್ನು.. ಭಗವಂತ ಅಭಿವ್ಯಕ್ತ ಗೊಳಿಸಿದ. ಇದರಿಂದ ಅವರು ಜ್ಞಾನಯೋಗಿಗಳಾದರು ಮತ್ತು\nಸಂಸಾರದಲ್ಲಿ ಜ್ಞಾನ ಪರಂಪರೆಯನ್ನು ಬೆಳೆಸಿ ಮುಕ್ತಿಯನ್ನು ಪಡೆದರು. ಅದೇ ರೀತಿ ಕರ್ಮಪ್ರಧಾನವಾಗಿರುವ\nಕರ್ಮಯೋಗಿಗಳಿಗೆ ತೇಜಸ್ಸಾಗಿ ನಿಂತು ಮುನ್ನೆಡೆಸಿದ ಭಗವಂತ, ಅವರಿಗೆ 'ತೇಜಸ್ಸಾಗಿ' ಮುಕ್ತಿ ಕರುಣಿಸುವವ.\nಬುದ್ಧಿಃ ಮತ್ತು ತೇಜಃ ಎನ್ನುವುದು ಭಗವಂತನ ಹೆಸರು. ಜ್ಞಾನದ ಅಪಾರ ಮತ್ತು ಅನಂತ ಕಡಲಾಗಿರುವ\nಭಗವಂತ “ಬುದ್ಧಿಃ. ದೇಹಬಲ, ಆತ್ಮಬಲ ಎಲ್ಲವೂ ಪೂರ್ಣಪ್ರಮಾಣದಲ್ಲಿರುವ ಸರ್ವಸಮರ್ಥ ಭಗವಂತ ತೇಜಃ.\n",
  "7.11": "ಬಲಮ್‌ ಬಲವತಾಂ ಚ ಅಹಮ್‌ ಕಾಮ ರಾಗ ವಿವರ್ಜಿತಮ್‌ ।\nಧರ್ಮ ಅವಿರುದ್ಧಃ ಭೂತೇಷು ಕಾಮಃ ಅಸ್ಮಿ ಭರತ ಋಷಭ -- ಬಲವಂತರ ಬಯಕೆ-ಒಲವುಗಳಿಲ್ಲದ ಬಲ\nನನ್ನಿಂದ. [ಬಲವಂತರೊಳಗಿದ್ದು ಬಲ ನೀಡುವುದರಿಂದ ಮತ್ತು ಕಾಮನೆಯಿಲ್ಲದ, ಅಸ್ಥಾನದಲ್ಲಿ ಬಳಸದ\nಬಲರೂಪನಾದ್ದರಿಂದ “ಕಾಮ ವಿವರ್ಜಿತ' ಮತ್ತು “ಬಲ' ನಾಮಕ.] ಭರತಶ್ರೇಷ್ಠ, ಜೀವಿಗಳಲ್ಲಿ ಧರ್ಮಕ್ಕೆ\nಅನುಗುಣವಾದ ಬಯಕೆ. ನನ್ನಿಂದ. [ಜೀವಿಗಳಲ್ಲಿದ್ದು ಧರ್ಮ ವೃದ್ಧಿಗೆ. ನೆರವಾಗಿ ಎಲ್ಲರಿಂದಲೂ\nಕಾಮಿತನಾದ್ದರಿಂದ 'ಧರ್ಮಾವಿರುದ್ಧ' ಮತ್ತು 'ಕಾಮ'ನಾಮಕ.]\n\nವಿಭೂತಿಯ ಸಮಸ್ತ ಮುಖಗಳನ್ನು ಕ್ರೋಡೀಕರಿಸಿ ಸಮಪಷ್ಟಿಯಾಗಿ ಹೇಳಿದ ಕೃಷ್ಣ, ಇಲ್ಲಿ ಮೂಲಭೂತವಾಗಿ\nಬದುಕಿನ ಎರಡು ಮುಖವನ್ನು ವಿವರಿಸುತ್ತಾನೆ. ಚೇತನದಲ್ಲಿರುವ ಬಲವನ್ನು ಕೃಷ್ಣ ಈ ಶ್ಲೋಕದಲ್ಲಿ\nಉಲ್ಲೇಖಿಸುತ್ತಾನೆ. ಬಲದಲ್ಲಿ ಅನೇಕ ವಿಧ. ಮುಂಡಕೋಪನಿಷತ್ತಿನಲ್ಲಿ ಹೇಳುವಂತೆ:\n\nನಾಯಮಾತ್ಮಾ ಪ್ರವಚನೇನ ಲಭ್ಯೋ ನ ಮೇಧಯಾ ನ ಬಹುನಾ ಶ್ರುತೇನ |\n\nಯಮೇವೈಷ ವೃಣುತೇ ತೇನ ಲಭ್ಯಸ್ತಸ್ಯೈಷ ಆತ್ಮಾ ವಿವೃಣುತೇ ತನೂಂ ಸ್ವಾಮ್‌ ॥೩-೨-೩॥\nನಾಯಮಾತ್ಮಾ ಬಲಹೀನೇನ ಲಭ್ಯೋ ನ ಚ ಪ್ರಮಾದಾತ್‌ ತಪಸೋ ವಾಪ್ಯಲಿಜ್ಗತ್‌ |\nಏತೈರುಪಾಯ್ಕೆರ್ಯತತೇ ಯಸ್ತು ವಿದ್ವಾಂಸ್ಪಸ್ಯೈಷ ಆತ್ಮಾ ವಿಶತೇ ಬ್ರಹ್ಮಧಾಮ ॥೩-೨-೪॥\n\n“ನ ಅಯಂ ಆತ್ಮಾ ಬಲಹೀನೇನ ಲಭ್ಯಃ” ಅಂದರೆ ಭಗವಂತನನ್ನು ಪಡೆಯುವುದು ದುರ್ಬಲರಿಗೆ ಸಾಧ್ಯವಿಲ್ಲ\nಎಂದರ್ಥ. ಇಲ್ಲಿ ಬಂದಿರುವ ಬಲ ದೇಹಬಲವಲ್ಲ. ಇದು ಭಗವಂತನ ಅನುಗ್ರಹದ ಬಲ. ಸ್ವರೂಪ ಯೋಗ್ಯತೆ\nಮತ್ತು ಜೊತೆಗೆ ಮನೋಬಲ. ಈ ಶ್ಲೋಕದಲ್ಲಿ ಹೇಳುವಂತೆ-ಅಧ್ಯಯನದಿಂದ, ಶಾಸ್ತ್ರ ಶ್ರವಣದಿಂದ\n\"“ಮನೋಬಲ' ವೃದ್ಧಿಯಾಗಬಹುದು, ಆದರೆ ಆತ್ಮಬಲವಿಲ್ಲದೆ ಭಗವಂತನನ್ನು ಕಾಣಲು ಸಾಧ್ಯವಿಲ್ಲ.\nಮಹಾಭಾರತ ತಾತ್ಪರ್ಯ ನಿರ್ಣಯದಲ್ಲಿ ಹೇಳುವಂತೆ:\n\nಯಸ್ಯ ದೇವೇ ಪರಾ ಭಕ್ತಿರ್ಯಥಾ ದೇವೇ ತಥಾ ಗುರೌ |\n\nತಸೆ ಟ್ಮತೇ ಕಥಿತಾ ಹ್ಯರ್ಥಾಃ ಪ್ರಕಾಶಂತೇ ಮಹಾತ್ಮನಃ ॥ ೧-೧೦೨॥\nಯಾರಲ್ಲಿ. ಭಗವಂತನ ಭಕ್ತಿ. ಮತ್ತು. ಆತ್ಮಬಲವಿದೆಯೋ; . ದೇವತೆಗಳಲ್ಲೂ, ಗುರುಗಳಲ್ಲೂ\nತಾರತಮ್ಯಪೂರ್ವಕವಾದ ಭಕ್ತಿಯಿದೆಯೋ- ಅಂತಹ ಮಹಾತ್ಮನಿಗೆ ಮಾತ್ರವೇ ವಿಷಯಗಳ ಸ್ಟುರಣವಾಗುತ್ತದೆ.\nಜ್ಞಾನದ ಬಲವಿದ್ದರೆ ಸಾಲದು, ಭಕ್ತಿಯ ಬಲಬೇಕು. ಭಗವಂತನ ಅನುಗ್ರಹಕ್ಕೆ ನಮ್ಮಲ್ಲಿ ಭಕ್ತಿಯನ್ನು\nಜಾಗೃತಗೊಳಿಸುವ ಗುರು ಅನುಗ್ರಹದ ಬಲವೂ ಮುಖ್ಯ. ಹೀಗೆ ಆತ್ಮ ಯೋಗ್ಯತೆಯ ಬಲ, ಸಾಧನೆಯ ಬಲ,\nಭಕ್ತಿಯ ಬಲ, ಶಾಸ್ತ್ರಾಧ್ಯಾಯನದ ಬಲ, ಗುರುಗಳ ಅನುಗ್ರಹದ ಬಲ, ಇವನ್ನೆಲ್ಲವನ್ನೂ ನಮಗೆ ಕೊಡುವವ ಆ\nಭಗವಂತ. ಆತ ಅನೇಕರೂಪದಲ್ಲಿ 'ಬಲ' ನಾಮಕನಾಗಿ ನಿಂತು ಜೀವ ಯೋಗ್ಯತೆಗನುಗುಣವಾಗಿ ವಿಶೇಷ\nಬಲವನ್ನು ಅನುಗ್ರಹಿಸುತ್ತಾನೆ.\nಸಾಮಾನ್ಯವಾಗಿ ಬಲದ ಹಿಂದೆ ಒಂದು ದೋಷವಿರುತ್ತದೆ. ಬಲ ಬಂದಾಗ ನಮಗೆ ಕೆಟ್ಟ ಕಾಮನೆ ಹುಟ್ಟುತ್ತದೆ.\nಆದರೆ ಭಗವಂತ ಕಾಮ-ರಾಗ ವಿವರ್ಜಿತ ಬಲ ಸ್ವರೂಪ. ನಮಗೆ ಕಾಮವರ್ಜಿತ ಬಲ ಕಲ್ಪನಾತೀತ. ಇಲ್ಲಿ ಕೃಷ್ಣ\n'ಕಾಮನೆ' ಬೇಡ ಎಂದು ಹೇಳುತ್ತಿಲ್ಲ. ಭಗವಂತನನ್ನು ತಿಳಿಯಬೇಕು', “ಭಕ್ತಿಯಿಂದ ಶಾಸ್ತ್ರಾಧ್ಯಾಯನ\nಮಾಡಬೇಕು' ಇತ್ಯಾದಿ ಕಾಮನೆಗಳು ನಮಗೆ ಅಗತ್ಯವಾಗಿ ಬೇಕು. ಯಾವ ಬಯಕೆ ನಮಗೆ ಧಾರಕ ಶಕ್ತಿಯಾಗಿ\nನಿಲ್ಲುತ್ತದೋ ಅಲ್ಲಿ ಕಾಮ ವಿವರ್ಜಿತನಾಗಿ' ಭಗವಂತ ನಿಂತ. ಇಲ್ಲಿ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ಸಮಸ್ತ ಜೀವಜಾತದಲ್ಲಿ\nಧರ್ಮಕ್ಕೆ ಅವಿರುದ್ಧವಾಗಿರುವ ಕಾಮನೆಯ ಹಿಂದೆ ನಾನಿದ್ದೇನೆ” ಎಂದು.\nಈ ಶ್ಲೋಕದಲ್ಲಿ ಕೃಷ್ಣ ಅರ್ಜುನನನ್ನು 'ಭರತರ್ಷಭ' ಎಂದು ಸಂಬೋಧಿಸುತ್ತಾನೆ. ಜ್ಞಾನಾನಂದದಲ್ಲಿ ರಥನಾದವ\n“ಭರತರ್ಷಭ'; ಭರತ(ವಾಯು) ಋಷಭ(ಅಣ್ಣ)ನಾಗಿ ಉಳ್ಳವ ಭರತರ್ಷಭ.\nಈ ಮೇಲಿನ ಶ್ಲೋಕದಲ್ಲಿ ಕೇವಲ ಒಳ್ಳೆಯ ಅಂಶದಲ್ಲಿ ಇರತಕ್ಕಂತಹ ತನ್ನ ವಿಭೂತಿಯನ್ನು ಕೃಷ್ಣ ವಿವರಿಸಿದ. ಈ\nಅನುಸಂಧಾನದಲ್ಲಿ ಗೀತೆಯನ್ನು ನೋಡಿದಾಗ, ಇಲ್ಲಿ ಕೆಲವರಿಗೆ ಒಂದು ಸಂಶಯ ಬರಬಹುದು. “ಒಳ್ಳೆಯದನ್ನು\nಮಾಡಿಸುವವನು ದೇವರು, ಕೆಟ್ಟದ್ದನ್ನು ಮಾಡಿಸುವುದು ಯಾವುದೋ ದುಷ್ಟಶಕ್ತಿ” ಎಂದು. ಅಂದರೆ ಎಲ್ಲವನ್ನೂ\nಭಗವಂತ ಮಾಡಿಸುವುದಲ್ಲ ಎನ್ನುವ ಸಂಶಯ ನಮ್ಮನ್ನು ಕಾಡಬಹುದು. ಈ ನಮ್ಮ ಸಂಶಯಕ್ಕೆ ಕೃಷ್ಣನ ಉತ್ತರ\nಮುಂದಿನ ಶ್ಲೋಕ.\n",
  "7.12": "ಯೇಚವಏವ ಸಾತ್ತ್ವಿಕಾಃ ಭಾವಾ ರಾಜಸಾಃ ತಾಮಸಾಃ ಚ ಯೇ।\n\nಮತ್ತಃ ಏವ ಇತಿ ತಾನ್‌ ವಿದ್ಧಿ ನ ತು ಅಹಮ್‌ ತೇಷು ತೇ ಮಯಿ-ಯಾವ ವಸ್ತುಗಳು ಸತ್ತ್ವಗುಣದ ಪ್ರಭಾವಕ್ಕೆ\nಒಳಗಾಗಿವೆ, ಮತ್ತು ಯಾವವು ರಜೋಗುಣ ಮತ್ತು ತಮೋಗುಣದ ಪ್ರಭಾವಕ್ಕೆ-ಅವೆಲ್ಲವೂ ನನ್ನಿಂದಾಗಿಯೇ\nಆಗಿವೆ ಎಂದು ತಿಳಿ. ನಾನು ಅವುಗಳ ಹಂಗಿನಲ್ಲಿಲ್ಲ. ಅವು ನನ್ನ ಹಂಗಿನಲ್ಲಿವೆ.\n\n೮.\n\nಪ್ರಪಂಚ ಎಂದರೆ ಅಂತರಂಗ ಮತ್ತು ಬಹಿರಂಗ. ಅಂತರಂಗ ಪ್ರಪಂಚದಲ್ಲಿ ತ್ರೈಗುಣ್ಯದ ಭಾವನೆಗಳು, ಬಾಹ್ಯಂಚದಲ್ಲಿ ತ್ರೈಗುಣ್ಯ ಪದಾರ್ಥಗಳು. ಸತ್ವ, ರಜಸ್ಸು ಮತ್ತು ತಮಸ್ಸು ಈ ಮೂರರ ಸಮಾವೇಶವೇ ಈಂಚ. ಮಣ್ಣು ತಮೋಗುಣದ, ನೀರು ರಜೋಗುಣದ ಮತ್ತು ಬೆಂಕಿ ಸತ್ವ ಗುಣದ ಸಂಕೇತ. ಆದ್ದರಿಂದ ಈ\nಪ್ರಪಂಚದಲ್ಲಿ ನಮಗೆ ಕಾಣುವ ಪ್ರತಿಯೊಂದು ವಸ್ತುವೂ ಕೂಡಾ ಈ ಮೂರರ ಸಮಾವೇಶ. ನಮ್ಮ ಅಂತರಂಗದ\nಭಾವನೆಗಳೂ ಕೂಡಾ ಈ ಮೂರು ಗುಣದ ಸಮಾವೇಶ. ನಮ್ಮಲ್ಲಿರುವ ವರ್ಣ ಪದ್ಧತಿ ಕೂಡಾ ತ್ರೈಗುಣ್ಯ\nಆಧಾರಿತ. ಎಲ್ಲರಲ್ಲಿಯೂ ಕೂಡಾ ಈ ಮೂರು ಗುಣಗಳಿವೆ. ಆದರೆ ಸತ್ವದ ಅಂಶ ಹೆಚ್ಚಾಗಿದ್ದು, ರಜಸ್ಸು ಮತ್ತು\nತಮಸ್ಸು ಕಡಿಮೆ ಇರುವವ ಬ್ರಾಹ್ಮಣ ವರ್ಣ; ರಜಸ್ಸಿನ ಅಂಶ ಹೆಚ್ಚಾಗಿದ್ದು ಅದರ ನಂತರ ಸತ್ವ ಮತ್ತು ತಮಸ್ಸು\nಇರುವವ ಕ್ಷತ್ರಿಯ; ರಜಸ್ಸು ಹೆಚ್ಚಾಗಿದ್ದು ಅದರ ನಂತರ ತಮಸ್ಸು ಮತ್ತು ಸತ್ವ ಗುಣ ಉಳ್ಳವ ವೈಶ್ಯ; ತಮೋಗುಣ\nಹೆಚ್ಚಾಗಿದ್ದು, ಅದರ ನಂತರ ರಜಸ್ಸು ಮತ್ತು ಸತ್ವ ಗುಣ ಉಳ್ಳವ ಶೂದ್ರ. ಈ ಎಲ್ಲಾ ವರ್ಣದವರೂ ಮೋಕ್ಷ\nಯೋಗ್ಯರೆ. ಸೃಷ್ಟಿಯ ಆದಿಯಲ್ಲಿ ಈ ಮೂರು ಗುಣಗಳ ಮಿಶ್ರಣವಾಗಿಯೇ ಸೃಷ್ಟಿ ಪ್ರಾರಂಭವಾಯಿತು. ಇಲ್ಲಿ ಶುದ್ಧ\nಸತ್ವ ಅನ್ನುವುದೊಂದಿಲ್ಲ. (ಗಣಿತಬದ್ಧವಾಗಿ ಹೇಗೆ ತ್ರೈಗುಣ್ಯದಿಂದ ಈ ಪ್ರಪಂಚ ನಿರ್ಮಾಣವಾಯಿತು\nಎನ್ನುವುದನ್ನು ಮಧ್ವಾಚಾರ್ಯರು ತಮ್ಮ ಭಾಗವತ ತಾತ್ಪರ್ಯನಿರ್ಣಯ ಗ್ರಂಥದಲ್ಲಿ ಸ್ಪಷ್ಟವಾಗಿ ವಿವರಿಸಿದ್ದಾರೆ.\nಇದೊಂದು ಸೃಷ್ಟಿಯ ಪ್ರಮೇಯ).\n\nದ\n೦0\nದ\n೦0\n\n. ೫ 8೩\n\nಹೀಗೆ ಪ್ರತಿಯೊಂದು ಪದಾರ್ಥದಲ್ಲಿ ಮೂರು ಅಂಶಗಳಿವೆ ಮತ್ತು ನಮ್ಮ ಭಾವದಲ್ಲಿಯೂ ಮೂರು ಅಂಶಗಳಿವೆ. ಈ\nಮೂರು ಗುಣಗಳ ಸಂಕೀರ್ಣ ಪ್ರಪಂಚ ಬಹಳ ವಿಚಿತ್ರ. ಇವು ಯಾವುದು ಒಳ್ಳೆಯದು, ಯಾವುದು ಕೆಟ್ಟದ್ದು ಎಂದು\nಮನುಷ್ಯ ತೀರ್ಮಾನ ಮಾಡಲಾಗದಷ್ಟು ಗೊಂದಲಗೆಡಿಸುತ್ತವೆ. ಆದರೆ ಇಲ್ಲಿ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ತ್ರೈಗುಣ್ಯ\nವರ್ಜಿತನಾಗಿ ಈ ಮೂರು ಗುಣಗಳನ್ನು ಕೊಡುತ್ತಿರುವವನು ನಾನು” ಎಂದು! ಪ್ರತಿಯೊಂದು ಜೀವದ ಜೀವ\nಸ್ವಭಾವಕ್ಕನುಗುಣವಾಗಿ, ಅದಕ್ಕೆ ಬೇಕಾದ ಗುಣ ಪ್ರವೃತ್ತಿಯನ್ನು ಕೊಡುವವ ಆ ಭಗವಂತ. ಯಾರಲ್ಲೂ ಯಾವ\nಕ್ರಿಯೆಯೂ ಭಗವಂತನ ಪ್ರೇರಣೆ ಇಲ್ಲದೇ ಆಗುವುದಿಲ್ಲ. ಹಿಂದೆ ವಿವರಿಸಿದಂತೆ ಜೀವನಿಗೆ ಸ್ವತಂತ್ರ\nಇಚ್ಛಾಪೂರ್ವಕ ಕ್ರಿಯೆ ಇಲ್ಲ. “ನಹಿ ಪ್ರತಿಬಿಂಬಸ್ಯ ಕ್ರಿಯಾ | ಸ ಹಿ ಬಿಂಬ ಕ್ರಿಯೈೆವ ಕ್ರಿಯಾವಾನ್‌ |. ಬಿಂಬದಲ್ಲಿ\nಕ್ರಿಯೆ ಇಲ್ಲದೆ ಪ್ರತಿಬಿಂಬದಲ್ಲಿ ಕ್ರಿಯೆ ಇಲ್ಲ. ಭಗವಂತನ ಅಧೀನವಾಗಿ ಈ ಮೂರು ಗುಣಗಳು ಈ ಪ್ರಪಂಚದಲ್ಲಿ\nತುಂಬಿಕೊಂಡಿವೆ. ಇದು ನಮ್ಮ ಜೀವ ಪಕ್ವವಾಗಿ ಮೋಕ್ಷವನ್ನು ಸೇರಲು ಭಗವಂತ ನಿರ್ಮಿಸಿರುವ ಪಾಠಶಾಲೆ.\nಭಗವಂತ ತ್ರೈಗುಣ್ಯ ವರ್ಜಿತ. ಆತ ತ್ರಿಗುಣದ ನಿಯಂತ್ರಣಕ್ಕೊಳಪಟ್ಟಿಲ್ಲ.. ಅದಕ್ಕಾಗಿ ಭಗವಂತನನ್ನು\n“ತ್ರಿಗುಣಾತೀತ ವಿದಾರಕ-ಪರಿತೋ ತೇಹಿಸುಭಕ್ತಿಂ- ಕರುಣಾಪೂರ್ಣ ಪರಪ್ರದ-ಚರಿತಂ ಜ್ಞಾಪಯಮೇತೇ”\nಎಂದು ಸ್ತುತಿಸುತ್ತಾರೆ. ಇಡೀ ಜಗತ್ತು ತ್ರಿಗುಣದ ನಿಯಂತ್ರಣಕ್ಕೊಳಪಟ್ಟಿದೆ ಆದರೆ ಭಗವಂತ ತ್ರಿಗುಣಾತೀತ.\n",
  "7.13": "ತ್ರಿಭಿಃ ಗುಣ ಮಯೈಃ ಭಾವೈಃ ಏಭಿಃ ಸರ್ವಮ್‌ ಇದಮ್‌ ಜಗತ್‌ ।\nಮೋಹಿತಮ್‌ ನ ಅಭಿಜಾನಾತಿ ಮಾಮ್‌ ಏಭ್ಯಃ ಪರಮ್‌ ಅವ್ಯಯಮ್‌-ತ್ರಿಗುಣಾತ್ಮಕವಾದ ಈ ಸೊತ್ತುಗಳಿಂದ\nಮೋಹಗೊಂಡ ಈ ಎಲ್ಲಾ ಜೀವಜಾತ ಇವುಗಳಿಂದಾಚೆಗಿರುವ, ಅಳಿವಿರದ ನನ್ನನ್ನು ತಿಳಿಯದಾಗಿದೆ.\n\nಇಡೀ ಜಗತ್ತು ತ್ರಿಗುಣಗಳಿಂದ ಮೋಹಿತವಾಗಿರುವುದರಿಂದ ಮತ್ತು ಈ ಮೂರು ಗುಣಗಳು ಎಲ್ಲಾ ಕಡೆ\nತುಂಬಿರುವುದರಿಂದ ನಮಗೆ ತ್ರಿಗುಣಾತೀತವಾದ ಯೋಚನೆ ಅಸಾಧ್ಯ. ಈ ಕಾರಣದಿಂದ ತ್ರಿಗುಣಾತೀತನೂ\nಅವ್ಯಯನೂ ಆದ ಆ ಭಗವಂತನನ್ನು ಪೂರ್ಣವಾಗಿ ಗ್ರಹಿಸಲು ಜೀವನಿಗೆ ಸಾಧ್ಯವಿಲ್ಲ... ಭಗವಂತನನ್ನು\nಅರಿಯಬೇಕಾದರೆ ನಾವು ಈ ತ್ರಿಗುಣದ ಚಕ್ರದಿಂದ ಹೊರಕ್ಕೆ ಬರಬೇಕು. ಆದರೆ ಹೊರ ಬರುವ ಮಾರ್ಗ ಎಂತು?\nಉತ್ತರ ಮುಂದಿನ ಶ್ಲೋಕ.\n",
  "7.14": "ದೈವೀ ಹಿ ಏಷಾ ಗುಣಮಯೀ ಮಮ ಮಾಯಾ ದುರತ್ಯಯಾ |\n\nಮಾಮ್‌ ಏವ ಯೇ ಪ್ರಪದ್ಯಂತೇ ಮಾಯಾಮ್‌ ಏತಾಮ್‌ ತರಂತಿ ತೇ-ಗುಣಮಯವಾದ ನನ್ನ ಮಾಯೆ\nತುಂಬಾ ಶಕ್ತಿಶಾಲಿ. ಅದನ್ನು ದಾಟುವುದು ಸುಲಭವಲ್ಲ. ಯಾರು ನನ್ನ ಲ್ಲಿ ಮೊರೆ ಹೋಗುತ್ತಾರೋ ಅವರು ಈ\nಮಾಯೆಯನ್ನು ದಾಟಾತ್ತಾರೆ.\n\nತ್ರಿಗುಣಾತ್ಮಕವಾದ ಈ ಮೂರು ಭಾವಗಳಲ್ಲಿ ಇನ್ನೊಂದು ಮುಖವಿದೆ. ತ್ರಿಗುಣದ ಮಾನಿನಿ(ಶ್ರೀ ಲಕ್ಷ್ಮಿಯೂ\nಕೂಡಾ ಮೂರು ಮುಖದವಳು. ಶ್ರೀ-ಭೂ-ದುರ್ಗ-ಇವು ತ್ರಿಗುಣವನ್ನು ನಿಯಂತ್ರಿಸುವ ಮೂರು ರೂಪಗಳು. ಈ\nಗುಣಮಯೀ ತಾಯಿ ಮಾಯೆಯಾಗಿ ಜಗತ್ತಿನಲ್ಲಿ ತುಂಬಿದ್ದಾಳೆ. ಇಡೀ ಜಗತ್ತನ್ನು ನಿಯಂತ್ರಿಸಬಲ್ಲ ಮಹಾ\nಶಕ್ತಿಸ್ವರೂಪ ಆ ಮಾಯೆ ಭಗವಂತನ ಅಧೀನ. ನಾವು ಭಗವಂತನನ್ನು ಕಾಣಬೇಕಾದರೆ ಈ ಮಾಯಾ\nಪರದೆಯನ್ನು ಸರಿಸಿ. ಕಾಣಬೇಕು. ಆದರೆ ನಮ್ಮಿಂದ ಅದು ಅಸಂಭವ. ಈ ಕಾರಣದಿಂದ ಭಗವಂತನನ್ನು\nಸೇರುವ ಏಕೈಕ ಮಾರ್ಗ ಭಗವಂತನಲ್ಲಿ ಪೂರ್ಣ ಶರಣಾಗತಿ. ಆತ ಈ ಮಾಯಾ ಪರದೆಯನ್ನು ಸರಿಸಿ ದರ್ಶನ\nಕೊಡಬಲ್ಲ. ಈ ಹಿಂದೆ ಹೇಳಿದಂತೆ ಸಂಸಾರದ ಮೋಹಪಾಶದಿಂದ ದೂರ ಸರಿದು ನಾರಾಯಣನಲ್ಲಿ ಶರಣಾದಲ್ಲಿ\nಆತ ನಮ್ಮನ್ನು ಈ ಮಾಯಾ ಪರದೆಯಿಂದ ದಾಟಿಸುತ್ತಾನೆ.\n\nಭಗವಂತನಲ್ಲದೆ.. ನನಗೆ ಬೇರೆ ಅಸ್ತಿತ್ವವಿಲ್ಲ ಎನ್ನುವ ಎಚ್ಚರದಿಂದ ನಾವು. ನಮ್ಮನ್ನು ಆತನಿಗೆ\nಅರ್ಪಿಸಿಕೊಳ್ಳಬೇಕು. ನವವಿಧ ಭಕ್ತಿಯಲ್ಲಿ ಇದು ಶ್ರೇಷ್ಠವಾದ ಭಕ್ತಿ. ಇದನ್ನು ಆತ್ಮನಿವೇದನ ಎನ್ನುತ್ತಾರೆ.\nಮೊದಲು ನಮ್ಮೊಳಗಿರುವ ಭಗವಂತನನ್ನು ಅರಿತು, ಅಹಂಕಾರ ಮಮಕಾರವನ್ನು ತೊರೆದು ನಮ್ಮನ್ನು\nಸಂಪೂರ್ಣವಾಗಿ ಭಗವಂತನಲ್ಲಿ ಅರ್ಪಿಸಿಕೊಂಡಾಗ ಭಗವದ್‌ ಸಾಕ್ಷಾತ್ಕಾರವಾಗುತ್ತದೆ. ಇಲ್ಲಿ ಮುಖ್ಯವಾಗಿ\nಬೇಕಾಗಿರುವುದು ಏಕಭಕ್ತಿ ಮತ್ತು ಏಕನಲ್ಲಿ ಶರಣಾಗತಿ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ \"ಯಾರು ನನಗೇ ಶರಣಾಗುತ್ತಾರೋ\nಅವರು ಪಾರಾಗಿಯೇ ಆಗುತ್ತಾರೆ\" ಎಂದು. ಕೃಷ್ಣನ ಈ ಮಾತನ್ನು ಕೇಳಿದಾಗ ನಮ್ಮನ್ನು ಕೆಲವು ಪ್ರಶ್ನೆಗಳು\nಕಾಡಬಹುದು. \"ಎಲ್ಲರೂ ಏಕೆ ಭಗವಂತನಲ್ಲಿ ಶರಣಾಗುವುದಿಲ್ಲ? ಕೆಟ್ಟತನ ಜನರಲ್ಲಿ ಹೇಗೆ ಬರುತ್ತದೆ?\" ಇತ್ಯಾದಿ.\nಬನ್ನಿ ನಮ್ಮ ಪ್ರಶ್ನೆಗೆ ಉತ್ತರವನ್ನು ಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ಹುಡುಕೋಣ.",
  "7.15": "ನಮಾಂ ದುಷ್ಕೃತಿನಃ ಮೂಢಾಃ ಪ್ರಪದ್ಯನ್ನೇ ನರ ಅಧಮಾಃ ।\nಮಾಯಯಾ ಅಪಹೃತ ಜ್ಞಾನಾಃ ಆಸುರಮ್‌ ಭಾವಮ್‌ ಆಶ್ರಿತಾಃ - ಕೆಡು ನಡೆಯ ತಿಳಿಗೇಡಿ ಹುಲು ಮನುಜರು,\nಮೈಯ ಸುಖದಲ್ಲೇ ಮೈಮರೆತು ಮಾಯೆಯಿಂದ ತಿಳಿವು ಮಂಕಾದವರು. ಇವರು ನನಗೆ ಶರಣಾಗುವುದಿಲ್ಲ.\n\nಕೃಷ್ಣ ಈ ಶ್ಲೋಕದಲ್ಲಿ ದುಷ್ಕೃತಿಗಳ ಬಗ್ಗೆ ಹೇಳುತ್ತಾನೆ. ಇವರಲ್ಲಿ ಎರಡು ವಿಧ. ಯಾವುದೋ ಪ್ರಾರಬ್ಧ\nಕರ್ಮಕ್ಕೊಳಗಾಗಿ-ಪರಿಸರದ ಪ್ರಭಾವದಿಂದ ಪಾಪದ ದಾರಿಯಲ್ಲಿ ಸಾಗುವವರು(ಉದಾ: ಕರ್ಣ , ಅಜಾಮಿಳ)\nಹಾಗೂ ಸ್ವಭಾವತಃ ಪಾತಕಿಗಳು(ಉದಾ: ದುರ್ಯೋಧನ, ಶಕುನಿ). ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ನನಗೆ ಶರಣಾದವರನ್ನು\nನಾನು ಮಾಯೆಯಿಂದ ಬಿಡಿಸುತ್ತೇನೆ. ಆದರೂ ಕೂಡಾ ಎಲ್ಲರೂ ನನಗೆ ಶರಣಾಗುವುದಿಲ್ಲ” ಎಂದು. ಸ್ವಭಾವತಃ\nದುಷ್ಕೃತಿಗಳಾದವರು ಎಂದೂ ಭಗವಂತನನ್ನು ಒಪ್ಪಿಕೊಳ್ಳುವುದಿಲ್ಲ. ಅವರಿಗೆ ಎಷ್ಟೇ ಬುದ್ಧಿವಾದ ಹೇಳಿದರೂ\nಅರ್ಥವಾಗುವುದಿಲ್ಲ. ಇಂತವರು ಮಾಯೆಯ ಬಲೆಯಲ್ಲಿ ಬಿದ್ದು ಇಂದ್ರಿಯದಲ್ಲೇ ಎಲ್ಲಾ ಸುಖವಿದೆ ಎಂದು ತಿಳಿದು\nಬದುಕುತ್ತಾರೆ. ಪ್ರಭಾವದಿಂದ ಮಾಯೆಯ ಬಲೆಗೆ ಬೀಳುವ ಸಜ್ಜನರಿಗೆ ಮರಳಿ ಸರಿದಾರಿಗೆ ಬರುವ ವ್ಯವಸ್ಥೆ\nಸೃಷ್ಟಿಯಲ್ಲಿದೆ. ಜೀವ ಸ್ವಭಾವವೇ ನೀಚವಾಗಿದ್ದರೆ ಅಂತವರನ್ನು ಎಂದೂ ತಿದ್ದಲು ಸಾಧ್ಯವಿಲ್ಲ. ಅವರು ಎಂದೂ\nಭಗವಂತನನ್ನು ತಿಳಿಯಲು ಪ್ರಯತ್ನಿಸುವುದಿಲ್ಲ. ಇವರು ದುಷ್ಕೃತ್ಯವೇ ತಮ್ಮ ಕರ್ತವ್ಯ ಎಂದು ತಿಳಿದ\nತಿಳಿಗೇಡಿಗಳೆನಿಸುತ್ತಾರೆ. ಇಂಥವರನ್ನು ಇಲ್ಲಿ ಕೃಷ್ಣ “ನರಾಧಮಃ' ಎಂದು ಸಂಬೋಧಿಸಿದ್ದಾನೆ. ಇವರನ್ನು ಸದಾ\nಮಾಯೆ ಆವರಿಸಿರುತ್ತದೆ. ಇಂತವರು ತಮಗೆ ಬುದ್ಧಿ ಇಲ್ಲ ಎಂದೂ ತಿಳಿದಿರುವುದಿಲ್ಲ! ಅವರು ಎಂದೂ\nಭಗವಂತನಲ್ಲಿ ಶರಣಾಗುವುದಿಲ್ಲ ಮತ್ತು ಭಗವಂತನನ್ನು ಸೇರುವುದಿಲ್ಲ.\n\nಪ್ರಭಾವದಿಂದ ದುಷ್ಕೃತ್ಯಕ್ಕಿಳಿದವರ ಬುದ್ಧಿಯನ್ನು ಮಾಯೆ ಆವರಿಸಿರುತ್ತದೆ. ಕಾಲ ಪಕ್ಚವಾದಾಗ ಅವರು\nಪರಿಸರದ ಲೌಕಿಕ ಪ್ರಭಾವದಿಂದ ಕಳಚಿಕೊಂಡು ಮರಳಿ ಭಗವಂತನಿಗೆ ಶರಣಾಗುತ್ತಾರೆ. ಇದಕ್ಕೆ ಉತ್ತಮ\nದೃಷ್ಟಾಂತ ಅಜಾಮಿಳನ ಜೀವನ ಕಥನ.\n\nಅಜಾಮಿಳ ಒಬ್ಬ ಬ್ರಾಹ್ಮಣ. ಸರಳ, ಮಿತಭಾಷಿ, ಸಾತ್ತ್ವಿಕ, ವಿದ್ವಾಂಸನಿದ್ದ. ಗುರು, ಅತಿಥಿ, ಹಿರಿಯರ ಸೇವೆ\nಮಾಡುತ್ತಿದ್ದ. ತನ್ನ ಕೈ ಹಿಡಿದ ಹೆಂಡತಿಯನ್ನೂ ಪ್ರೀತಿಸುತ್ತಿದ್ದ. ಒಂದು ದಿನ ಆತ ಕಾಡಿನಲ್ಲಿ ಸುಂದರಿಯಾದ\nಒಬ್ಬಳು ಹೆಣ್ಣನ್ನು, ಅರೆನಗ್ನ ಸ್ಥಿತಿಯಲ್ಲಿ ನೋಡಿ ಆಕರ್ಷಣೆಗೊಳಪಟ್ಟ. ತನ್ನ ಹೆಂಡತಿ ಮತ್ತು ತಂದೆ\nತಾಯಿಯರನ್ನು ಮರೆತು, ತಾನು ಕಂಡ ಕಾಡಿನ ಹುಡುಗಿಯ ಸಂಗದಲ್ಲಿ, ಲೋಕವನ್ನು ಮರೆತ. ಆಕೆಯನ್ನು\nಸಂತೋಷಪಡಿಸಲು ಮಾಡಬಾರದ ಕೆಲಸವನ್ನೆಲ್ಲಾ ಮಾಡಿದ. ಕುಡುಕನಾದ, ಕಳ್ಳತನ ಮಾಡಿದ, ಜೂಜಾಡಿದ.\nಕಾಡಿನಲ್ಲಿ ಆಕೆಯೊಂದಿಗೆ ಸಂಸಾರ ಬೆಳೆಯಿತು, ಮಕ್ಕಳಾದವು. ಕೊನೆಯ ಮಗನ ಹೆಸರು 'ನಾರಾಯಣ\".\nಒಂದಿರುಳು ಅಜಾಮಿಳನಿಗೆ ಘೋರ ರೂಪದ ಯಮದೂತರೇ ಕಣ್ಣೆದುರು ನಿಂತಂತಾಯಿತು. ಅವರ ಕೈಯಲ್ಲಿ\nಯಮಪಾಶ! ಅಜಾಮಿಳನಿಗೆ ನಿಜಕ್ಕೂ ಭಯವಾಯಿತು. ತನ್ನ ಮಗ 'ನಾರಾಯಣ' ನನ್ನು ಕೂಗಿ ಕರೆದ! - ಆಗ\nಮಗನ ಬದಲು ಆತನಿಗೆ ವಿಷ್ಣು ದೂತರು ಕಾಣಿಸುತ್ತಾರೆ. ಎಚ್ಚರಗೊಂಡ ಆತನಿಗೆ ತಾನು ಮಾಡಿದ ತಪ್ಪಿನ\nಅರಿವಾಗುತ್ತದೆ. ಹಳಿತಪ್ಪಿ ಚಲಿಸುತ್ತಿದ್ದ ಆತನನ್ನು ಭಗವಂತ ಪುನಃ ಸರಿಯಾದ ದಾರಿಯಲ್ಲಿ ತಂದು ಉದ್ಧಾರ\nಮಾಡುತ್ತಾನೆ. ನಂತರದ ದಿನಗಳಲ್ಲಿ ಆತ ಮಹಾತ್ಮನಾಗಿ ಬದುಕಿ ತನ್ನ ಸಾಧನೆಯಿಂದ ಮೋಕ್ಷವನ್ನು\nಪಡೆಯುತ್ತಾನೆ.\n\nನಮ್ಮಲ್ಲಿ ಸಾತ್ವಿಕತೆ ಮತ್ತು ಜ್ಞಾನ ಅನೇಕ ಜನ್ಮಗಳ ಫಲದಿಂದ ಬಂದಿರುತ್ತದೆ. ಯಾವುದೋ ಕೆಟ್ಟ ಕಾರಣದಿಂದ\nನಾವು ದಾರಿತಪ್ಪಿದಾಗ, ಕರುಣಾಮಯನಾದ ಭಗವಂತ ನಮ್ಮನ್ನು ಶಿಕ್ಷಿಸುವ ಬದಲು ಕ್ಷಮಿಸಿ ಉದ್ಧಾರ\nಮಾಡುತ್ತಾನೆ. ಎಂತಹ ತಪ್ಪನ್ನೂ ಕೂಡಾ ಕ್ಷಮಿಸುವ ಕಾರುಣ್ಯಮೂರ್ತಿ ಆ ಭಗವಂತ. ಭಗವಂತ ನಮಗೆ\nಕೊಡುವ ದುಃಖ- ತಾಯಿ ತನ್ನ ಮಗುವನ್ನು ತಿದ್ದಲು ಕೊಡುವ ಶಿಕ್ಷೆಯಂತೆ. ಆತನ ಶಿಕ್ಷೆ ಕಾರುಣ್ಯದ ರಕ್ಷೆ. ಆತ\nಯಾರನ್ನೂ ದ್ವೇಷಿಸುವುದಿಲ್ಲ. ಎಲ್ಲರ ಅಪರಾಧವನ್ನೂ ಸಹಿಸುವ ಭಗವಂತ ಸಹಿಷ್ಣು.\n\nಭಗವಂತ ಅವರವರ ಸ್ವಭಾವಕ್ಕೆ ತಕ್ಕಂತೆ ಅವರವರ ವ್ಯಕ್ತಿತ್ವ ವಿಕಾಸಗೊಳಿಸುತ್ತಾನೆ. ಜೀವ ಸ್ವಭಾವವನ್ನು ಆತ\nಎಂದೂ ಬದಲಿಸುವುದಿಲ್ಲ. ಪಾಪಿಗಳಾದವರಿಗೆ ಪಾಪದ ಫಲ, ಪುಣ್ಯವಂತರಿಗೆ ಪುಣ್ಯದ ಫಲ. ಈ ವ್ಯವಸ್ಥೆ ಎಂದೂ\nಬದಲಾಗುವುದಿಲ್ಲ. ಈ ಕಾರಣದಿಂದ ಪ್ರಪಂಚದಲ್ಲಿ ನಾವು ಎಲ್ಲಾ ವಿಧದ ಜನರನ್ನು ಕಾಣುತ್ರೇವೆ.\nಸಾಮಾನ್ಯವಾಗಿ ಪ್ರಪಂಚದಲ್ಲಿ ಭಗವದ್ಭಕ್ತರು ಮತ್ತು ಜ್ಞಾನಿಗಳು ಅಲ್ಪಸಂಖ್ಯಾತರು. ಯಾವ ಕಾಲದಲ್ಲೂ ಕೂಡಾ\nಇವರು ಬಹು ಸಂಖ್ಯೆಯಲ್ಲಿ ಇರುವುದಿಲ್ಲ.\n\nಹರಿಕಥಾಮೃತಸಾರದಲ್ಲಿ ದಾಸರು ಸಾತ್ವಿಕರು, ತಾಮಸರು ಮತ್ತು ರಾಜಸರ ಬಗ್ಗೆ ಈ ರೀತಿ ಸೊಗಸಾಗಿ\n\nಹಾಡಿದ್ದಾರೆ:\n\nಪ.\n\nಕತ್ವಸತ್ವರು ಸತ್ವರಾಜಸ ಸತ್ವತಾಮಸ ಮೂವರೂ-\nಜ ಸತ್ವಾಧಿಕಾರಿಗಳು ಭಗವದ್ಭಕ್ತರೆನಿಸುವರು |\nನಿತ್ಯಬದ್ಧರು ರಜೋರಜರುತ್ಪತ್ತಿ ಭೂಸ್ವರ್ಗದೊಳು ನರಕದಿ-\nಪ್ರಥ್ವಿಯೊಳು ಸಂಚರಿಸುತಿಪ್ಪರು ರಾಜಸ್ತಾಮಸರು॥|\n\n೮.\n\nತಮಸ್ಸಾತ್ತ್ವಿಕರೆನಿಸಿಕೊಂಬರು ಅಮಿತನಾಖ್ಯಾತಾಸುರರಗಣ-\nತಮೋರಾಜಸರೆನಿಸಿಕೊಂಬರು ದೈತ್ಯ ಸಮುದಾಯ |\n\nತಮಸ್ತಾಮಸ ಕಲಿ ಪುರಂಧ್ರಿಯು ಅಮಿತ ದುರ್ಗುಣಪೂರ್ಣ-\nಸರ್ವಧರ್ಮರೊಳಧಮಾಧಮದುರಾತ್ಮನು ಕಲಿಯೆನಿಸಿಕೊಂಬ |\n\nಮಾಯೆಯ ಪ್ರಭಾವ ನಮ್ಮ ಮೇಲೆ ಕಾಲಕ್ಕನುಗುಣವಾಗಿರುತ್ತದೆ. ಸಾತ್ವಿಕ ಯುಗದಲ್ಲಿ ಸಾತ್ವಿಕ ಸ್ವಭಾವ ಎಷ್ಟು\nಬಲಿಷ್ಟ ಎಂದರೆ ಅದು ಸಾತ್ವಿಕರು ತಾಮಸ ಪ್ರಭಾವಕ್ಕೆ ಒಳಗಾಗದೇ ಶುದ್ಧವಾಗಿರುವಂತೆ ಮಾಡುತ್ತದೆ. ಆದರೆ\nಕಲಿಯುಗದಲ್ಲಿ ಎಲ್ಲರೂ ಬಹಳ ಸುಲಭವಾಗಿ ತಾಮಸ ಪ್ರಭಾವಕ್ಕೊಳಗಾಗುತ್ತಾರೆ. ಒಂದು ವೇಳೆ ಅದನ್ನು\nಮೀರಿ ಭಗವಂತನತ್ತ ಮನಸ್ಸು ಹರಿದರೆ ಅದು ಪರಮಶ್ರೇಷ್ಠ. ಇದಕ್ಕಾಗಿ “ಕಲಿಯುಗದಲ್ಲಿ ಹರಿನಾಮ ನೆನೆದರೆ\nಕುಲಕೋಟಿ ಉದ್ಧಾರವಾಗುವುದು' ಎನ್ನುತ್ತಾರೆ. ಕಲಿಯುಗದಲ್ಲಿ ತಾಮಸ ಪ್ರಭಾವಕ್ಕೊಳಗಾಗಿ ಮಾಡುವ ಶಪ್ಪಿಗೆ\nಶಿಕ್ಷೆ ಕಡಿಮೆ. ಹಾಗೇ ಪುಣ್ಯಕ್ಕೆ ಮಹಾಫಲ. ದುಷ್ಕೃತಿಗಳ ಬಗ್ಗೆ ವಿವರಿಸಿದ ಕೃಷ್ಣ, ಪುಣ್ಯವಂತ ಸಜ್ಜನರ ವಿಧವನ್ನು\nಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ವಿವರಿಸುತ್ತಾನೆ.\n",
  "7.16": "ಚತುರ್ವಿಧಾಃ ಭಜಂತೇ ಮಾಮ್‌ ಜನಾಃ ಸುಕೃತಿನಃ ಅರ್ಜುನ ।\n\nಆರ್ತಃ ಜಿಜ್ಞಾಸು: ಅರ್ಥ ಅರ್ಥೀ ಜ್ಞಾನೀ ಚ ಭರತ ಋಷಭ-ಓ ಭರತ ವಂಶದ ವೀರ ಅರ್ಜುನಾ, ಪುಣ್ಯವಂತರಾದ\nನಾಲ್ಕು ಬಗೆಯ ಜನರು ನನ್ನಲ್ಲಿ ಭಕ್ತಿ ಇಡುತ್ತಾರೆ: ಸಂಕಟದಲ್ಲಿರುವವರು, ಸಿರಿಯನ್ನು ಬಯಸುವವರು, ತಿಳಿಯ\nಬಯಸುವವರು ಮತ್ತು ತಿಳಿದವರು.\n\nದುಷ್ಕೃತಿಗಳ ಬಗ್ಗೆ ಮೊದಲು ವಿವರಿಸಿದ ಕೃಷ್ಣ ಈ ಶ್ಲೋಕದಲ್ಲಿ ಸುಕೃತಿಗಳ ಬಗ್ಗೆ ವಿವರಿಸುತ್ತಾನೆ. ಭಗವಂತನ\nಕಡೆಗೆ ಸಾಗುವುದು ಒಂದು ಸರಳರೇಖೆಯ ದಾರಿ ಇದ್ದಂತೆ. ಅದು ಕವಲು ದಾರಿ ಅಲ್ಲ. ಈ ಸರಳರೇಖೆಯಲ್ಲಿ\nಭಗವಂತನಿಗೆ ಬೆನ್ನು ಹಾಕಿ ಸಾಗುವವರು ಸ್ವಭಾವತಃ ದುಷ್ಟೃತಿಗಳು. ಭಗವಂತನಿಗೆ ಬೆನ್ನು ಹಾಕಿ ಸಾಗಿ,\nನಂತರ ಅರಿವು ಮೂಡಿ ಪುನಃ ಭಗವಂತನತ್ತ ಮುಖ ಹಾಕುವವರು ದುಷ್ಕೃತಿಗಳಾಗಿದ್ದು ಸುಕೃತಿಗಳಾಗುವವರು.\nಇನ್ನು ಭಗವಂತನತ್ತ ಮುಖ ಮಾಡಿ ಸಾಗುವವರು ಸ್ವಭಾವತಃ ಸುಕೃತಿಗಳು. ಇವರು ಭಗವಂತನನ್ನು\nಭಜಿಸುವವರು. ಈ ಸುಕೃತಿಗಳಲ್ಲಿ ನಾಲ್ಕು ವಿಧ: (೧) ಆರ್ತಃ (೨) ಜಿಜ್ಞಾಸುಃ (೩) ಅರ್ಥ ಅರ್ಥೀ (೪) ಜ್ಞಾನಿ.\n\nಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ನನ್ನನ್ನು ನಾಲ್ಕು ವಿಧದಲ್ಲಿ ಭಜಿಸುವ ಸುಕೃತ ಜನರಿದ್ದಾರೆ” ಎಂದು. ಇಲ್ಲಿ ಭಜಿಸುವುದು\nಅಥವಾ 'ಭಜನೆ' ಅಂದರೆ 'ಭಕ್ತಿಯಿಂದ ಭಗವಂತನನ್ನು ಆರಾಧಿಸುವುದು' ಎಂದರ್ಥ. ಭಜ ಸೇವಾಯಾಂ ಧಾತು.\nಭಗವಂತನನ್ನು ಎಲ್ಲವುದಕ್ಕಿಂತ ಹಿರಿದಾಗಿ ಮತ್ತು ಹೆಚ್ಚಾಗಿ ಪ್ರೀತಿಸಿ, ಆ ಪ್ರೀತಿಗೆ ತಕ್ಕಂತೆ ನಡೆದುಕೊಳ್ಳುವುದು\nಭಜನೆ. ಈ ರೀತಿ ಭಜಿಸುವವರಲ್ಲಿ ಮೊದಲನೆಯವರು ಆರ್ತರು.\n\nಮನುಷ್ಯ ಯಾವುದೋ ಒಂದು ತೊಂದರೆಗೆ ಸಿಕ್ಕಿಕೊಂಡಾಗ, ದುಃಖಕ್ಕೊಳಗಾದಾಗ, ಪರಿಹಾರ ಕೋರಿ\nದೇವರಲ್ಲಿ ಪ್ರಾರ್ಥನೆ ಮಾಡುತ್ತಾನೆ. ಇದು ಆರ್ತಃ ಭಕ್ತಿ. ಈ ಭಕ್ತಿಯಲ್ಲಿ ಅತ್ಯಂತ ಕೆಳ ಮಟ್ಟದಿಂದ ಅತ್ಯಂತ ಶ್ರೇಷ್ಠ\n\nಮಟ್ಟ ವನ್ನು ಕಾಣಬಹುದು. ಕಷ್ಟ ಬಂದಾಗ ದೇವರನ್ನು ಅರ್ತನಾಗಿ ಭಜಿಸಿ, ಸುಖ ಬಂದಾಗ ಸಂಪೂರ್ಣ\nಮರೆತರೆ- ಸಂಕಟ ಬಂದಾಗ ವೆಂಕಟರಮಣ' ಎನ್ನುವಂತೆ ಅದು ಅತ್ಯಂತ ಕೆಳಮಟ್ಟದ ಆರ್ತಭಕ್ತಿಯಾಗುತ್ತದೆ.\nಆರ್ತ ಭಕ್ತಿಯಲ್ಲಿ ಅತ್ಯಂತ ಶ್ರೇಷ್ಠ ಮಟ್ಟದ ಭಕ್ತಿಗೆ ಉತ್ತಮ ದೃಷ್ಟಾಂತ ದ್ರೌಪದಿ. ಸಭೆಯಲ್ಲಿ ಆಕೆಯ ಮಾನಭಂಗ\nಪ್ರಸಂಗ ಎದುರಾದಾಗ, ಆಕೆ ಕೃಷ್ಣನನ್ನು ಆರ್ತನಾದದಿಂದ ಕೂಗಿ ಭಜಿಸುತ್ತಾಳೆ.(ಇಲ್ಲಿ ದ್ರೌಪದಿ ಕೃಷ್ಣನನ್ನು\nನಿರಂತರ ಭಜಿಸುತ್ತಿದ್ದಳು ಎನ್ನುವುದನ್ನು ನಾವು ಮರೆಯಬಾರದು). ಮೊಸಳೆ ತನ್ನ ಕಾಲನ್ನು ಕಚ್ಚಿ ಹಿಡಿದಾಗ\nಗಜೇಂದ್ರ ಮಾಡಿದ್ದೂ ಕೂಡಾ ಆರ್ತ ಭಕ್ತೆ.\n\nಆರ್ತ ಭಕ್ತಿಯಲ್ಲಿ ಒಂದು ಸಮಸ್ಯೆ ಇದೆ. ಸಾಮಾನ್ಯವಾಗಿ ನಮಗೆ ಸುಖ ಬಂದಾಗ ನಾವು ಭಗವಂತನನ್ನು\nಮರೆತುಬಿಡುತ್ತೇವೆ. ನಮ್ಮೆಲ್ಲಾ ಐಶ್ವರ್ಯ-ಸಂಪತ್ತು “ನಮ್ಮ ದುಡಿಮೆಯ ಫಲ' ಅಂದುಕೊಳ್ಳುತ್ತೇವೆ. ಆಗ ನಮಗೆ\nದೇವರು ನನಪಿಗೆ ಬರುವುದೇ ಇಲ್ಲ. ಆದರೆ ಒಂದು ವೇಳೆ ಏನಾದರೂ ಸಮಸ್ಯೆ ಬಂದರೆ-ಮೊದಲು ನೆನಪಿಗೆ\nಬರುವುದು ದೇವರು. ಎಂದೆಂದೂ 'ದೇವರು ಸುಖವನ್ನೆ ಕೆ ಕೊಟ್ಟ ' ಎಂದು ಯೋಚಿಸದ ನಾವು, ಕಷ್ಟ ಬಂದಾಗ\n\"ದೇವರು ನನಗೇಕೆ ಹೀಗೆ ಮಾಡಿದ' ಎನ್ನ ಲಾರಂಭಿಸುತ್ತೇವೆ! ಸಾಮಾನ್ಯವಾಗಿ ಜನರು ಸಂಕಟ ಬಂದಾಗ\nಮೊದಲು ಜ್ಯೋತಿಷಿಗಳ ಬಳಿ ಹೋಗುತ್ತಾರೆ. ಜ್ಯೋತಿಷಿಗಳು ಒಂದು ಪರಿಹಾರ ಮಾರ್ಗವನ್ನು ಸೂಚಿಸುತ್ತಾರೆ.\nನವಗ್ರಹ ಪೂಜೆ, ನಾಗಾರಾಧನೆ, ಗಣಪತಿ ಪೂಜೆ, ದೇವೀ ಆರಾಧನೆ ಇತ್ಯಾದಿ. ಇಲ್ಲಿ ಕೆಲವು ಶಾಸ್ತ್ರ ಜ್ಞಾನವಿಲ್ಲದ\nಮತ್ತು ಅಧ್ಯಾತ್ಮದ ಅರಿವಿಲ್ಲದ ಸಾಮಾನ್ಯ ಜ್ಯೋತಿಷಿಗಳು, ಜನರಿಗೆ ಸರಿಯಾದ ಮಾರ್ಗದರ್ಶನ ಮಾಡದೇ\nತಪ್ಪು ಮಾರ್ಗ ತೋರಿಸುವ ಸಾಧ್ಯತೆ ಹೆಚ್ಚು. ಕೆಲವರು. “ನೀನು ವಿಷ್ಣು ಪೂಜೆ ಮಾಡಿದ್ದರಿಂದ ದೇವಿ\nಕೋಪಗೊಂಡಿದ್ದಾಳೆ!!!” ಎಂಬಿತ್ಯಾದಿ ಅಸಂಬದ್ಧ ಹೇಳಿಕೆ ಕೊಟ್ಟು ಸ; ಜನರನ್ನು ದಾರಿತಪ್ಪಿ ಸುವ ಪ್ರಸಂಗವಿದೆ.\nಹೀಗಾದಾಗ ಸಾಮಾನ್ಯ ಜನರು ಎಲ್ಲಾ ದೇವತೆಗಳನ್ನು ಬೇರೆ ಬೇರೆಯಾಗಿ ಪೂಜಿಸಿ, ಏಕಭಕ್ತಿಯಿಂದ ದೂರ\nಸರಿಯುತ್ತಾರೆ. ಇದರಿಂದಾಗಿ ಭಗವಂತನನ್ನು ಪ್ರೀತಿಸುವ ಬದಲು ಭಯದಿಂದ “ದೇವರಿಂದ ನನಗೆ ಯಾವ\nತೊಂದರೆ ಆಗದಿರಲಿ' ಎನ್ನುವಂತೆ ಭಕ್ತಿ ಮಾಡುವ ಸಾಧ್ಯತೆ ಇದೆ! ಈ ಎಲ್ಲಾ ಕಾರಣದಿಂದ ನಿರಂತರಭಕ್ತಿ ಮತ್ತು\nಏಕಭಕ್ತಿ ಆರ್ತಭಕ್ತರಲ್ಲಿ ಇಲ್ಲದೇ ಇರುವ ಸಾಧ್ಯತೆ ಹೆಚ್ಚು.\n\nಆರ್ತರು ಕಷ್ಟವನ್ನು ನೀಗುವಂತೆ ಭಗವಂತನಲ್ಲಿ ಭಕ್ತಿ ಮಾಡಿದರೆ, ಜಿಜ್ಞಾಸುಗಳು ಜ್ಞಾನಕ್ಕಾಗಿ ಭಗವಂತನಲ್ಲಿ ಭಕ್ತಿ\nಮಾಡುತ್ತಾರೆ. ಅದೇ ರೀತಿ ಅರ್ಥಾರ್ಥಿಗಳು ಐಹಿಕ ಸಂಶತ್ತಿಗಾಗಿ, ಐಶ್ವರ್ಯಕ್ಕಾಗಿ, ಏನನ್ನೊ 6\nಪಡೆಯುವುದಕ್ಕಾಗಿ ಭಗವಂತನನ್ನು ಪೂಜಿಸುತ್ತಾರೆ.\n\nಈ ಮೂರು ಭಕ್ತರಿಗಿಂತ ಭಿನ್ನ ನಾಲ್ಕನೇ ವಿಧದ ಭಕ್ತ. ಆತ ಜ್ಞಾನಿ. ಆತ ಏನೋ ಬೇಕು ಅಥವಾ ಬೇಡ ಎಂದು\nಭಗವಂತನನ್ನು ಪೂಜಿಸುವುದಿಲ್ಲ; ಬದಲಿಗೆ ಭಗವಂತನ ಮಹಿಮೆಯನ್ನು ಸಂಪೂರ್ಣ ತಿಳಿದ ಆತ ಸಹಜವಾಗಿ\nಭಗವಂತನನ್ನು ಅನನ್ಯವಾಗಿ ಪ್ರೀತಿಸುತ್ತಿರುತ್ತಾನೆ. ಈತನಲ್ಲಿ ಏಕಭಕ್ತಿ ಮತ್ತು ನಿರಂತರ ಭಕ್ತಿ ಇರುತ್ತದೆ.\nಯಾವುದೇ ಐಹಿಕ ಫಲಾಪೇಕ್ಷೆಯಿಂದ ಈತ ಭಗವಂತನನ್ನು ಭಜಿಸುವುದಿಲ್ಲ.\n\nಮುಂದಿನ ಶ್ಲೋಕಕ್ಕೆ ಹೋಗುವ ಮೊದಲು ಇಲ್ಲಿ ನಾವು ಏಕಭಕ್ತಿ ಅಂದರೆ ಏನು ಎನ್ನುವುದನ್ನು ಸ್ಪಷ್ಟವಾಗಿ\nತಿಳಿದಿರಬೇಕು. ಏಕಭಕ್ತಿ ಎಂದರೆ ಎಲ್ಲಾ ದೇವತೆಗಳನ್ನು, ಗುರು-ಹಿರಿಯರನ್ನು ನಿರ್ಲಕ್ಷಿಸಿ ಕೇವಲ ಭಗವಂತನನ್ನು\nಪೂಜಿಸುವುದಲ್ಲ. ಒಂದು ವೇಳೆ ನಾವು ಹೀಗೆ ಮಾಡಿದರೆ ಅದು ಭಗವಂತನನ್ನು ಅವಮಾನ ಮಾಡಿದಂತೆ.\nಉದಾಹರಣೆಗೆ ನಮಗೆ ಯಾವುದೋ ತೊಂದರೆ ಬಂದಾಗ ಜ್ಯೋತಿಷಿಯೊಬ್ಬರು “ನವಗ್ರಹ ಶಾಂತಿ' ಮಾಡಿಸಿ\n\nಪರಿಹಾರವಾಗುತ್ತದೆ ಎಂದು ಹೇಳುತ್ತಾರೆ. ಹೀಗೆ ಹೇಳಿದಾಗ ನಾವು ಅದನ್ನು ನಿರ್ಲಕ್ಷಿಸಿ ಕೇವಲ ಭಗವಂತನನ್ನು\nಮಾತ್ರ ನಾನು ಜಭಜಿಸುತ್ತೇನೆ, ಭಗವಂತನ ಅಧೀನ ದೇವತೆಯ ಪೂಜೆಯ ಅಗತ್ಯವೇನು ಎಂದು\nತಿಳಿದುಕೊಂಡರೆ ಅದು ತಪ್ಪಾಗುತ್ತದೆ. ನವಗ್ರಹಗಳ ಪರಿವಾರ ಸಹಿತನಾಗಿ ಕೂತ ಭಗವಂತನಿಗೆ ಮಾಡುವ\nಪೂಜೆ “ನವಗ್ರಹ ಪೂಜೆ'. ಇದು ಯಾವುದರಿಂದ ಸಮಸ್ಯೆ ಬಂತೋ ಅದರ ಮುಖಂಡನಾಗಿ ಕುಳಿತ ಭಗವಂತನ\nಪೂಜೆ. ಭಗವಂತನ ಸಮಸ್ತ ಪರಿವಾರದ ವೈಭವನ್ನು ನೆನೆಸಿಕೊಂಡು ಯಾವುದೇ ಪೂಜೆ ಮಾಡಿದರೂ ಅದು\nಶ್ರೇಷ್ಠ ಪೂಜೆ ಎನಿಸುತ್ತದೆ. ಸಮಸ್ತ ದೇವತೆಗಳ ಸಹಿತನಾದ ಭಗವಂತನ ಉಪಾಸನೆಯೇ ಏಕಭಕ್ತಿ. ಭಗವಂತ\nಏಕಾಕಿ ಅಲ್ಲ. ಆತ ಅನಂತ ಪ್ರಜಾಪತಿ. ಆದ್ದರಿಂದ ಭಗವಂತನನ್ನು ಪ್ರಧಾನವಾಗಿಟ್ಟುಕೊಂಡು ಇತರ\nದೇವತೆಗಳನ್ನು ಭಗವಂತನ ಪರಿವಾರವಾಗಿ ತಿಳಿದು ನಿಷ್ಠೆಯಿಂದ ಪೂಜಿಸಬೇಕು. ಇದು ದೇವರನ್ನು ಸೇರಲು\nನಮಗೆ ಮಾರ್ಗದರ್ಶನ ಮಾಡುವ ದೇವತೆಗಳೂ ಇಷ್ಟಪಡುವ ಅತಿಶ್ರೇಷ್ಠ ಭಕ್ತಿ. ಒಂದು ವೇಳೆ ನಾವು\nಭಗವಂತನನ್ನು ಮರೆತು ಕೇವಲ ಒಂದು ದೇವತೆಯನ್ನು ಪೂಜಿಸಿದರೆ ಆ ದೇವತೆ ನಮ್ಮ ಪೂಜೆಯನ್ನು\nಸ್ವೀಕರಿಸದೇ ಇರಬಹುದು. ಪೂಜೆ ಪರಿಪೂರ್ಣವಾಗಬೇಕಾದರೆ ಸಾವು. ಏಕಭಕ್ತಿಯನ್ನು ಭಗವಂತನಲ್ಲಿ\nತೋರಬೇಕು.\n\nಗುರುಭಕ್ತಿ. ಕೂಡಾ ಇದೇ ರೀತಿ. ಗುರುಭಕ್ತಿಯಲ್ಲಿ. ನಾವು. ಕಾಣಬೇಕಾಗಿರುವುದು. ಗುರುವಿನ\nಅಂತರಂಗದೊಳಗಿರುವ ಭಗವಂತನನ್ನು. ಜ್ಞಾನಿ ಎಲ್ಲವುದರಲ್ಲೂ ಅದರ ಅಂತರ್ಯಾಮಿಯಾದ ಭಗವಂತನನ್ನು\nಕಾಣುತ್ತಾ, ಐಹಿಕ ಫಲಾಪೇಕ್ಷೆ ಇಲ್ಲದ ಏಕಭಕ್ತಿ ಮತ್ತು ನಿರಂತರ ಭಕ್ತಿಯನ್ನು ರೂಢಿಸಿಕೊಂಡಿರುತ್ತಾನೆ.",
  "7.17": "ತೇಷಾಮ್‌ ಜ್ಞಾನೀ ನಿತ್ಯಯುಕ್ತಃ ಏಕಭಕ್ತೆಃ ವಿಶಿಷ್ಯತೇ |\n\nಪ್ರಿಯಃ ಹಿ ಜ್ಞಾನಿನಃ ಅತ್ಯರ್ಥಮ್‌ ಅಹಮ್‌ ಸಃ ಚ ಮಮ ಪ್ರಿಯಃ -ಅವರಲ್ಲಿ ತಿಳಿದವನು ಮಿಗಿಲಾದವನು ;\nನನ್ನಲ್ಲೇ ಭಕ್ತಿಯನ್ನಿಟ್ಟು, ನನ್ನನ್ನೇ ಸದಾ ನೆನೆಯುವವನು. ತಿಳಿದವನಿಗೆ ನಾನೆಂದರೆ ತುಂಬಾ ಇಷ್ಟ, ಅವನೆಂದರೆ\nನನಗೂ ತುಂಬಾ ಇಷ್ಟ.\n\nಮೇಲೆ ಹೇಳಿದ ನಾಲ್ಕು ರೀತಿಯ ಭಕ್ತರಲ್ಲಿ ಜ್ಞಾನಿ ಎಲ್ಲರಿಗಿಂತ ಶ್ರೇಷ್ಠ. ಆತ ಜ್ಞಾನಪೂರ್ವಕವಾಗಿ ಯಾವುದೇ\nಫಲಾಪೇಕ್ಷೆ ಇಲ್ಲದೆ ಭಗವಂತನನ್ನು ತಿಳಿದು ಸಹಜವಾಗಿ ಪ್ರೀತಿಸುತ್ತಾನೆ. ಹಿಂದಿನ ಅಧ್ಯಾಯಗಳಲ್ಲಿ\nನೋಡಿದಂತೆ ನಾವು ಏನನ್ನು ಮಾಡುತ್ತೇವೋ ಅದನ್ನೇ ಪಡೆಯುತ್ತೇವೆ. ಭಗವಂತನನ್ನು ಹೇಗೆ ಕಾಣುತ್ತೇವೋ\nಹಾಗೇ ಭಗವಂತ ನಮ್ಮನ್ನು ಕಾಣುತ್ತಾನೆ. ಈ ಕಾರಣದಿಂದ ಜ್ಞಾನಪೂರ್ವಕವಾದ, ಫಲಾಪೇಕ್ಷೆ ಇಲ್ಲದ,\nಏಕಭಕ್ತಿಯುಳ್ಳ ಜ್ಞಾನಿ ಭಗವಂತನಿಗೆ ಬಹಳ ಹತ್ತಿರದಲ್ಲಿರುತ್ತಾನೆ.\n",
  "7.18": "ಉದಾರಾಃ ಸರ್ವೇ ಏವ ಏತೇ ಜ್ಞಾನೀ ತು ಆತ್ಮಾ ಏವ ಮೇ ಮತಮ್‌ |\n\nಆಸ್ಥಿತಃ ಸಃ ಹಿ ಯುಕ್ತಾತ್ಮಾ ಮಾಮ್‌ ಏವ ಅನುತ್ತಮಾಂ ಗತಿಮ್‌ -ಇವರೆಲ್ಲರೂ ದೊಡ್ಡವರೇ. ತಿಳಿದವನಂತೂ-\nತೀರಾ ನನ್ನವನು ಎಂದು ನನ್ನ ತೀರ್ಮಾನ. ಏಕೆಂದರೆ ಅವನು ಹಿರಿಯ ನೆಲೆಯಾದ ನನ್ನಲ್ಲೇ ಬಗೆ ನೆಟ್ಟು\nನನ್ನಲ್ಲೇ ನೆಲೆಗೊಂಡವನು.\n\nಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ಭಕ್ತಿ ಮಾರ್ಗದಲ್ಲಿ ನಡೆಯುವ ಈ ಎಲ್ಲಾ ರೀತಿಯ ಸುಕೃತಿಗಳೂ ಉತ್ತಮರೇ ; ಆದರೆ ಜ್ಞಾನಿ\nಮಾತ್ರ ನನಗೆ ತುಂಬಾ ಹತ್ತಿರದವನು ಮತ್ತು ಆತ್ಮೀಯ” ಎಂದು. ಏಕೆಂದರೆ ನಮಗೆ ತಿಳಿದಂತೆ ಜ್ಞಾನವಿಲ್ಲದ\nಭಕ್ತಿ ಪೂರ್ಣಭಕ್ತಿ ಆಗುವುದಿಲ್ಲ. ಜ್ಞಾನಪೂರ್ವಕವಾಗಿ ಭಕ್ತಿ ಮಾಡುವವ ನೇರವಾಗಿ ಭಗವಂತನನ್ನು ಹೋಗಿ\nಸೇರುತ್ತಾನೆ. ಆದ್ದರಿಂದ ಅದು ಶ್ರೇಷ್ಠವಾದ ಭಕ್ತಿ.\n\nಜ್ಞಾನಿಗಳು. ಆರ್ತರಾಗಿರಬಹುದು, ಜಿಜ್ಞಾಸುಗಳಾಗಿರಬಹುದು. ಅಥವಾ ಅರ್ಥಾರ್ಥಿಗಳಾಗಿರಬಹುದು\n(ಉದಾಹರಣೆಗೆ ಅರ್ಜುನ). ಆದರೆ. ಎಲ್ಲಾ ಆರ್ತರು, ಜಿಜ್ಞಾಸುಗಳು ಮತ್ತು ಅರ್ಥಾರ್ಥಿಗಳು\nಜ್ಞಾನಿಗಳಾಗಿರಬೇಕೆಂದೇನಿಲ್ಲ. ಜ್ಞಾನಿಗೆ ಸದೃಶವಾದ ಭಕ್ತಿ ಇನ್ನೊ ದಿಲ್ಲ. ಜ್ಞಾನಿಯ ಮನಸ್ಸು ಸದಾ\nಭಗವಂತನಲ್ಲಿ ನೆಟ್ಟಿರುತ್ತದೆ. ಭಕ್ತಿಯ ಮಾರ್ಗದಲ್ಲಿ ಸಾಗುವ ಎಲ್ಲರೂ ದೊಡ್ಡವರಾದರೂ ಕೂಡಾ, ಜ್ಞಾನಿ ಮಾತ್ರ\nಭಗವಂತನಿಗೆ ಅತೀ ಆತ್ಮೀಯ.\n\nಮೇಲೆ ಹೇಳಿದಂತೆ ಜ್ಞಾನಿ ಅರ್ಥಾರ್ಥಿಯಾಗಿರಬಹುದು. ಈ ವಿಚಾರ ನಿಮಗೆ ಸ್ವಲ್ಪ ಗೊಂದಲವೆನಿಸಬಹುದು.\nಪ್ರಹ್ಲಾದನ ಜೀವನದ ಒಂದು ಘಟನೆಯನ್ನು ನೋಡಿದರೆ ಈ ವಿಚಾರ ನಮಗೆ ಅರ್ಥವಾಗುತ್ತದೆ. ಪ್ರಹ್ಲಾದನ ಕಥೆ\nನಮಗೆಲ್ಲರಿಗೂ ತಿಳಿದಿದೆ. ಆತ ಮಹಾನ್‌ ಜ್ಞಾನಿ. ಇಂತಹ ಪ್ರಹ್ಲಾದ ತನ್ನ ತಂದೆ ಹಿರಣ್ಯಾಕ್ಷನನ್ನು ಕೊಂದ\nನರಸಿಂಹ ರೂಪಿ ಭಗವಂತನಲ್ಲಿ ಒಂದು ಪ್ರಾರ್ಥನೆ ಮಾಡುತ್ತಾನೆ. “ನನ್ನ ತಂದೆ ತಿಳುವಳಿಕೆ ಇಲ್ಲದೆ, ನಿನ್ನ\nಮಹತ್ವ ಗೊತ್ತಿಲ್ಲದೇ, ನಿನ್ನನ್ನು ನಿಂದೆ ಮಾಡಿದ. ಆ ದೋಷಕ್ಕೆ ಎಂದೂ ಪರಿಹಾರ ಇಲ್ಲ ಎನ್ನುವುದು ನನಗೆ\nತಿಳಿದಿದೆ. ಆದರೂ ಅಜ್ಞಾನದಿಂದ ಆತ ಮಾಡಿದ ತಪ್ಪನ್ನು ಕ್ಷಮಿಸು” ಎಂದು. ಇಲ್ಲಿ ಯಾವುದೇ ಸ್ವಾರ್ಥ ನಮಗೆ\nಕಾಣುವುದಿಲ್ಲ. ಆದ್ದರಿಂದ ಇದು ಜ್ಞಾನಿ ಅರ್ಥಾರ್ಥಿ ಹೇಗೆ ಆಗುತ್ತಾನೆ ಎನ್ನು ವುದಕ್ಕೆ ಉತ್ತಮ ನಿದರ್ಶನ.\n",
  "7.19": "ಬಹೂನಾಮ್‌ ಜನ್ಮನಾಮ್‌ ಅಂತೇ ಜ್ಞಾನವಾನ್‌ ಮಾಮ್‌ ಪ್ರಪದ್ಯತೇ |\n\nವಾಸುದೇವಃ ಸರ್ವಮ್‌ ಇತಿ ಸಃ ಮಹಾ ಅತ್ಮಾ ಸು ದುರ್ಲಭಃ -- ಬಹಳ ಜನ್ಮಗಳ ಸಾಧನೆಯ ಕೊನೆಯಲ್ಲಿ\nಅರಿವು ಪಡೆದು ನನ್ನನ್ನು ಸೇರುತ್ತಾನೆ. 'ವಾಸುದೇವನೇ ಎಲ್ಲೆಡೆ ತುಂಬಿರುವ ಪೂರ್ಣತತ್ವ' ಎಂದರಿತ ಅಂತಹ\nಹಿರಿಯ ವ್ಯಕ್ತಿ ತುಂಬಾ ವಿರಳ.\n\nಜೀವನದಲ್ಲಿ ಜ್ಞಾನಿ ಎನಿಸಿಕೊಳ್ಳುವುದು ಸುಲಭದ ಕೆಲಸವಲ್ಲ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಬಹೂನಾಂ ಜನ್ಮನಾಮಂತೇ\nಜ್ಞಾನವಾನ್‌ ಮಾಂ ಪ್ರಪದ್ಯತೇ” ಎಂದು. ಅಂದರೆ “ಅನೇಕಾನೇಕ ಜನ್ಮಗಳ ಸಾಧನೆಯಿಂದ, ಜಿಜ್ಞಾಸೆಯಿಂದ,\nಅಧ್ಯಯನದಿಂದ ಜ್ಞಾನ ಬರುತ್ತದೆ ಮತ್ತು ಇಂತಹ ಜ್ಞಾನಿ ಸಹಜವಾಗಿ ನನಗೆ ಶರಣಾಗುತ್ತಾನೆ”. ಹಿಂದಿನ\nಅಧ್ಯಾಯಗಳಲ್ಲಿ ಹೇಳಿದಂತೆ ಜ್ಞಾನ ಸಂಪಾದನೆ ಒಂದು ಜನ್ಮದ ಸಾಧನೆ ಅಲ್ಲ. ಆದರೆ ಒಂದು ಜನ್ಮದಲ್ಲಿ\nಮಾಡಿದ ಅಧ್ಯಾತ್ಮ ಸಾಧನೆ ಎಂದೂ ನಷ್ಟವಾಗುವುದಿಲ್ಲ. ಹುಟ್ಟುವಾಗಲೇ ನಾವು ನಮ್ಮ ಹಿಂದಿನ ಜನ್ಮದ\nಅಧ್ಯಾತ್ಮ ಸಾಧನೆಯ ಜ್ಞಾನವನ್ನು ಹೊತ್ತು ಹುಟ್ಟುತ್ತೇವೆ. ಇದು ಮಾನವನಿಗೆ ಭಗವಂತನ ಮಹಾ ಪ್ರಸಾದ.\nಜ್ಞಾನ ಎನ್ನುವುದು ನೂರಾರು ಜನ್ಮಗಳ ಸಂಚಯನ. ಇದು ಒಂದು ಜನ್ಮದಲ್ಲಿ ಪಡೆಯಬಹುದಾದ ವಿಷಯವಲ್ಲ.\nನಾವು ಎಷ್ಟು ತಿಳಿದಿದ್ದರೂ ಕೂಡಾ ಅದು ಕಡಿಮೆಯೇ. ಭಗವಂತನೇ ಹೇಳುವಂತೆ ವೇದದ ಪೂರ್ಣ ಅರ್ಥವನ್ನು\nಭಗವಂತನಲ್ಲದೆ ಇನ್ಯಾರೂ ತಿಳಿದಿಲ್ಲ.\n\nಹೀಗೆ ಯಾರು ಜನ್ಮ ಜನ್ಮಗಳ ಸಾಧನೆಯಿಂದ ಜ್ಞಾನಿ ಎನಿಸುತ್ತಾನೋ ಆತ ಸರ್ವಸ್ವವನ್ನೂ ವಾಸುದೇವನಲ್ಲಿ\nಅರ್ಪಿಸಿ ಮೋಕ್ಷ ಪಡೆಯುತ್ತಾನೆ. ಇಲ್ಲಿ ವಾಸುದೇವ ಎನ್ನುವ ಭಗವಂತನ ನಾಮಕ್ಕೆ ವಿಶೇಷ ಅರ್ಥವಿದೆ.\nವಾಸು-ದೇವ-ವಾಸುದೇವ. ಭಗವಂತ ವಾಸು, ಅಂದರೆ ತನ್ನನ್ನು ತಾನು ಮುಚ್ಚಿಕೊಂಡವನು. ಯಾವಾಗ ನಾವು\nಜ್ಞಾನವನ್ನು ಪಡೆದು, ಹದಿನೈದು ಬೇಲಿಗಳನ್ನು ದಾಟಿ, ಸಮಾಧಿ ಸ್ಥಿತಿಯಿಂದ ಆಳಕ್ಕಿಳಿದು, ಹದಿನಾರನೇ\nಜೀವಸ್ವರೂಪವನ್ನು ಕಾಣುತ್ತೇವೋ, ಆಗ ಭಗವಂತನ ಸಾಕ್ಷಾತ್ಕಾರವಾಗುತ್ತದೆ. ಈ ಸ್ಥಿತಿಯಲ್ಲಿ ಮುಚ್ಚಿಕೊಂಡ\nಭಗವಂತ ದೇವನಾಗಿ ತೆರೆದುಕೊಳ್ಳುತ್ತಾನೆ. ಭಗವಂತನನ್ನು ಕಾಣಬೇಕಾದರೆ ಮೊದಲು ನಾವು ನಮ್ಮನ್ನು\nಕಾಣಬೇಕು. ನಮ್ಮ ಅರಿವೇ ನಮಗಿಲ್ಲದೆ ಭಗವಂತನನ್ನು ಕಾಣುವುದು ಅಸಾಧ್ಯ. ನಾವು ನಮ್ಮ\nಜೀವಸ್ವರೂಪವನ್ನು ಕಂಡಾಗ, ಅದರೊಳಗಿನಿಂದ ಸಾಕ್ಷಾತ್ಕಾರವಾಗುವ ಭಗವಂತ ದೇವಃ. ನಾವು ನಮ್ಮ\nಪಂಚಕೋಶಗಳ ಪರದೆಯಲ್ಲಿದ್ದಾಗ ವಾಸುವಾಗಿ; ಜ್ಞಾನ ಸಂಪಾದನೆಯಿಂದ ಪರದೆಯಿಂದಾಚೆಗೆ ಬಂದು ಜೀವ\nಸ್ವರೂಪವನ್ನು ಕಂಡಾಗ ದೇವನಾಗಿ ದರ್ಶನ ಕೊಡುವ ಭಗವಂತ ವಾಸುದೇವಃ.\n\nಹೀಗೆ ಅನೇಕ ಜನ್ಮಗಳ ಸಾಧನೆಯಿಂದ ಜ್ಞಾನ ಸಂಪಾದಿಸಿ, ಭಗವಂತನನ್ನು ತಿಳಿದು, ಭಗವಂತನಲ್ಲಿ\nಶರಣಾಗುವ ಜ್ಞಾನಿ ಬಹಳ ಹಿರಿಯ. ಜಗತ್ತಿನಲ್ಲಿ ಇಂತವರು ಬಹಳ ವಿರಳ ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.\n\nಇಲ್ಲಿ ನಾವು ನಾಲ್ಕು ಬಗೆಯ ಭಕ್ತರನ್ನು ಮತ್ತು ಅವರಲ್ಲಿ ಜ್ಞಾನಿಯ ಶ್ರೇಷ್ಠತೆಯನ್ನು ನೋಡಿದೆವು. ಈ ನಾಲ್ಕು\nಬಗೆಯಲ್ಲೂ ಸೇರದೇ ಪಂಚಮರಾಗಿ ಹೊರಗುಳಿಯುವ ಜನರು ಏಕೆ ಹಾಗಿರುತ್ತಾರೆ ಎನ್ನುವ ವಿಚಾರವನ್ನೂ ಕೃಷ್ಣ\nವಿವರಿಸಿದ. ಮನುಷ್ಯ ನಿಜವಾದ ಅಧ್ಯಾತ್ಮ ಮಾರ್ಗದಲ್ಲಿ ನಡೆಯದೇ ಎಲ್ಲಿ ಎಡವುತ್ತಾನೆ ಎನ್ನುವ ಅಂಶಗಳನ್ನು\nಕೃಷ್ಣ ಈ ಅಧ್ಯಾಯದ ಮುಂದಿನ ಭಾಗದಲ್ಲಿ ವಿವರಿಸುತ್ತಾನೆ.\n",
  "7.20": "ಕಾಮೈಃ ತೈಃ ತೈಃ ಹೃತ ಜ್ಞಾನಾಃ ಪ್ರಪದ್ಯಂತೇ ಅನ್ಯ ದೇವತಾಃ |\n\nತಮ್‌ ತಮ್‌ ನಿಯಮಮ್‌ ಆಸ್ಥಾಯ ಪ್ರಕೃತ್ಯಾ ನಿಯತಾಃ ಸ್ವಯಾ-ಯಾವ ಯಾವುದೋ ಬಯಕೆಗಳಿಂದ ಅರಿವು\nಅಳಿದವರು ತಮ್ಮ ಸ್ವಭಾವ -ಸಂಸ್ಕಾರಗಳಿಗೆ ತಕ್ಕಂತೆ ಆಯಾ ಕಟ್ಟಲೆಗಳಿಗೆ ಕಟ್ಟುಬಿದ್ದು ಬೇರೆ ಬೇರೆ\nದೇವತೆಗಳಿಗೆ ಮೊರೆಹೋಗುತ್ತಾರೆ.\n\nಕೃಷ್ಣ ಹಿಂದಿನ ಅಧ್ಯಾಯಗಳಲ್ಲಿ ಹೇಳಿರುವ ವಿಚಾರವನ್ನು ಮತ್ತೆ ಒತ್ತು ಕೊಟ್ಟು ಇಲ್ಲಿ ವಿವರಿಸುತ್ತಾನೆ. ಮನುಷ್ಯ\nಅಧ್ಯಾತ್ಮ ಮಾರ್ಗದಿಂದ ದೂರ ಸರಿಯಲು ಮೂಲ ಕಾರಣ ಅವನ ಹುಚ್ಚು ಬಯಕೆಗಳು. ಇದು ನಮ್ಮ ಅರಿವಿಗೆ\nದೊಡ್ಡ ಅಡ್ಡಗೋಡೆ. ಬಯಕೆಗಳನ್ನು ನಿಯಂತ್ರಿಸಲು ಸಾಧ್ಯವಾಗದೇ ಇದ್ದಾಗ, ಮನುಷ್ಯ ಅಧ್ಯಾತ್ಮದ\nಬೆನ್ನುಹತ್ತುವ ಬದಲು ಬಯಕೆಗಳ ಬೆನ್ನು ಹತ್ತುತ್ತಾನೆ. ಬಯಕೆಗಳ ಈಡೇರಿಕೆಗೋಸ್ಕರ ಮಾಡಬಾರದ್ದನ್ನು\nಮಾಡುತ್ತಾ ಹೋಗುತ್ತಾನೆ ಮತ್ತು ಅಧಃಪತನವನ್ನು ಹೊಂದುತ್ತಾನೆ.\n\nಬಯಕೆಗಳ ಬೆನ್ನುಹತ್ತಿದಾಗ ಬಯಕೆ ಅರಿವನ್ನು ನಿಯಂತ್ರಿಸಲಾರಂಭಿಸುತ್ತದೆ. ಈ ಸಮಯದಲ್ಲಿ ಯಾರಾದರೂ\n\"ನಿನ್ನ ಇಷ್ಟಾ ರ್ಥ ಸಿದ್ಧಿಗಾಗಿ ಈ ದೇವಾಲಯಕ್ಕೆ ಹೋಗು' ಎಂದರೆ ಆತ ಅಲ್ಲಿಗೆ ಹೋಗುತ್ತಾನೆ . ಹೀಗೆ ಇಷ್ಟಾ ರ್ಥ\nಸಿದ್ಧಿ ಎಲ್ಲಿ ಸಾಧ್ಯ ಎಂದು ಸುದ್ದಿ ಬಂತೋ ಅಲ್ಲಿಗೆ ಭೇಟಿ ಕೊಡಲಾರಂಭಿಸುತ್ತಾನೆ. ಇದರಿಂದಾಗಿ ಆತ ಮೂಲ\nಅಧ್ಯಾತ್ಮ ತತ್ವವನ್ನು ಬಿಟ್ಟು, ಏಕಭಕ್ತಿಯಿಂದ ದೂರ ಸರಿದು, ಎಲ್ಲಿ ತನ್ನ ಅಪೇಕ್ಷೆ ಈಡೇರುತ್ತದೋ ಅಲ್ಲಿ, ಆಯಾ\nದೇವತೆಗಳನ್ನು ತನ್ನ ಭೌತಿಕ ಬಯಕೆಗಳನ್ನು ಈಡೇರಿಸುವಂತೆ ಬೇಡಿ ಪೂಜಿಸಲಾರಂಭಿಸುತ್ತಾನೆ. ಅದಕ್ಕಾಗಿ\nಯಾವುದ್ಯಾವುದೋ ವೃತಾಚರಣೆ ಮಾಡಲಾರಂಭಿಸುತ್ತಾನೆ. ಇದರಿಂದಾಗಿ ಆತ ನಿಜವಾದ ಭಗವಂತನ\nಉಪಾಸನೆಯ ಮಾರ್ಗದಿಂದ ದೂರ ಸರಿಯುತ್ತಾನೆ. ಏಕಭಕ್ತಿ ಉಪಾಸನೆಯಿಂದ ಈ ರೀತಿಯ ಅಲ್ಪ ಬಯಕೆ\nಎಂದೂ ಈಡೇರುವುದಿಲ್ಲ. ಏಕೆಂದರೆ “ಯದನುಗ್ರಹಮಿಚ್ಛಾಮಿ ತಸ್ಯ ವಿತ್ತಂ ಹರಾಮ್ಯಹಂ' ಭಕ್ತರ ಸಂಪತ್ತನ್ನು\nಇಲ್ಲದಂತೆ ಮಾಡಿ, ಪರೀಕ್ಷಿಸಿ, ನಂತರ ಅವರನ್ನು ಉದ್ಧರಿಸುವುದೇ ಭಗವಂತನ ಸಂಕಲ್ಪ. ನಮಗೆ ಏನು ಬೇಕು\nಎನ್ನುವುದು ನಮಗಿಂತ ಚೆನ್ನಾಗಿ ಭಗವಂತನಿಗೆ ಗೊತ್ತು. ಆತನ ಅನುಗ್ರಹ ಮಹಾಪ್ರಸಾದ. ಈ ಅರಿವು\nಬಯಕೆಗಳ ಬೆನ್ನು ಹತ್ತಿದವರಿಗೆ ಇರುವುದಿಲ್ಲ ಮತ್ತು ಇದರಿಂದ ಅವರು ಭಗವಂತನ ಅನುಗ್ರಹದಿಂದ\nವಂಚಿತರಾಗುತ್ತಾರೆ.\n\nಏಕೆ ಹೀಗೆ? ಏಕೆ ಎಲ್ಲರೂ ಒಂದೇ ರೀತಿಯಾಗಿ ಭಗವಂತನನ್ನು ಪೂಜಿಸುವುದಿಲ್ಲ? ಇದಕ್ಕೆ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ\n“ತನ್ನಂ ನಿಯಮಮಾಸ್ಥಾಯ ಪ್ರಕೃತ್ಯಾ ನಿಯತಾಃ ಸ್ವಯಾ”, “ಪ್ರತಿಯೊಂದು ಜೀವಕ್ಕೂ ಅದರದ್ದೇ ಆದ ಪ್ರಕೃತಿ\nಇದೆ” ಎಂದು. [ಇಲ್ಲಿ 'ಪ್ರಕೃತಿ' ಎಂದರೆ ಒಂದು “ಜೀವ ಸ್ವಭಾವ' ಹಾಗೂ ಇನ್ನೊಂದು \"ಪರಿಸರ ಮತ್ತು\nಹುಟ್ಟಿಬಂದ ಮನೆತನದ ಸಂಸ್ಕಾರ(genes and environmental force)' ] ಮನುಷ್ಯನ ಈ ಜೀವಸ್ವಭಾವವನ್ನು\nಎಂದೂ ಯಾರಿಂದಲೂ ಬದಲಿಸಲು ಸಾಧ್ಯವಿಲ್ಲ. ಒಬ್ಬೊಬ್ಬರ ಸ್ವಭಾವ ಒಂದೊಂದು ತರಹ. ಈ ಕಾರಣದಿಂದ\nಏಕರೂಪ ಸ್ವಭಾವ ಈ ಜಗತ್ತಿನಲ್ಲಿಲ್ಲ. ಈ ಭೂಮಿಯ ಮೇಲೆ ಎಷ್ಟೋ ಭಾರಿ ಭಗವಂತ ಮತ್ತು ಅನೇಕ\nಮಹಾತ್ಮರು ಅವತರಿಸಿ ಬಂದು ಸತ್ಯವನ್ನು ಭೋಧನೆ ಮಾಡಿದರೂ ಕೂಡಾ, ಏಕಧರ್ಮ ಸ್ಥಾಪನೆ ಆಗಲಿಲ್ಲ.\nಕಾರಣ ಏನೆಂದರೆ ಸ್ವತಃ ಭಗವಂತನೇ ಬಂದು ಹೇಳಿದರೂ ಕೂಡಾ-ಸತ್ಯವನ್ನು ತಿಳಿಯಬಲ್ಲ ಜೀವಸ್ವಭಾವವುಳ್ಳ\nಜೀವ ಮಾತ್ರ ಆ ಸತ್ಯವನ್ನು ಗ್ರಹಿಸಬಲ್ಲವು, ಉಳಿದ ಜೀವಗಳಿಗೆ ಸತ್ಯವನ್ನು ಗ್ರಹಿಸುವ ಶಕ್ತಿ ಇರುವುದಿಲ್ಲ. ಇದು\n\nತೀರಾ ಸಹಜ. ಆದ್ದರಿಂದ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ಸತ್ಯವನ್ನು ಒಪ್ಪುವುದಕ್ಕೂ ಕೂಡಾ ಜೀವಕ್ಕೆ ಯೋಗ್ಯತೆ ಬೇಕು”\nಎಂದು. ಹೀಗೆ ಜೀವ ಸ್ವರೂಪದ ಯೋಗ್ಯತೆಗನುಗುಣವಾಗಿ ಅವರವರಿಗೆ ಇಷ್ಟವಾಗುವ ದೇವತಾ ಉಪಾಸನೆ\nಪ್ರಪಂಚದಲ್ಲಿ ನಡೆಯುತ್ತದೆ. ಈ ಕಾರಣದಿಂದ ಪ್ರಪಂಚದಲ್ಲಿ ಎಲ್ಲರೂ ನಿಜವಾದ ಭಗವದ್‌ ಭಕ್ತರಾಗಲು\nಸಾಧ್ಯವಿಲ್ಲ, ಅದು ಕೇವಲ ಸಾತ್ವಿಕ ಚೇತನಕ್ಕೆ ಮಾತ್ರ ಸಾಧ್ಯ.\n",
  "7.21": "ಯಃ ಯಃ ಯಾಮ್‌ ಯಾಮ್‌ ತನುಮ್‌ ಭಕ್ತಃ ಶ್ರದ್ಧಯಾ ಅರ್ಚಿತುಮ್‌ ಇಚ್ಛತಿ ।\nತಸ್ಯ ತಸ್ಯ ಅಚಲಾಮ್‌ ಶ್ರದ್ಧಾಮ್‌ ತಾಮ್‌ ಏವ ವಿದಧಾಮಿ ಅಹಮ್‌-ಯಾರು ಯಾವ ದೇವತಾರೂಪವನ್ನು\nಭಕ್ತಿಯಿಟ್ಟು ಶ್ರದ್ಧೆಯಿಂದ ಪೂಜಿಸಬಯಸುತ್ತಾರೋ ಅವರಿಗೆ ಅಂತಹದ್ದೇ ಶ್ರದ್ಧೆಯನ್ನು ನಾನು ಗಟ್ಟಿಗೊಳಿಸುತ್ತೇನೆ.\n\nಭಗವಂತನೆಂಬ ಅಸಾಧಾರಣ ಶಕ್ತಿ ತನ್ನ ದೇವತಾ ಪರಿವಾರದೊಂದಿಗೆ ಈ ಜಗತ್ತನ್ನು ನಿಯಂತ್ರಿಸುತ್ತಿದೆ ಎನ್ನುವ\nಎಚ್ಚರ ಇಲ್ಲದೇ, ಭಗವಂತನ ಮೇಲಿನ ಏಕಭಕ್ತಿ ಬಿಟ್ಟು, ಕೇವಲ ಒಂದು ದೇವತೆಯನ್ನು ಶ್ರದ್ಧೆಯಿಂದ ಪೂಜೆ\nಮಾಡಲು ಆಯ್ಕೆ ಮಾಡಿಕೊಂಡವರಿಗೆ -“ಯಾವ ದೇವತೆಯ ಮೇಲೆ ಭಕ್ತಿ ಇದೆಯೋ ಅದನ್ನೇ\nಆಚಲವಾಗಿಸುತ್ತೇನೆ” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ!\n\nಮನುಷ್ಯ ಶ್ರದ್ಧೆಯ ಸ್ವರೂಪ. ಯಾವುದರ ಬಗೆಗೆ ಶ್ರದ್ಧೆ ಮೂಡಿತೋ ಅದೇ ಅವನಲ್ಲಿ ಬೆಳೆದುಕೊಂಡು\nಹೋಗುತ್ತದೆ. ಯಾವ ದೇವತಾ ಶಕ್ತಿಯನ್ನು ಶ್ರದ್ಧೆಯಿಂದ ಆರಾಧನೆ ಮಾಡಿದೆವೋ ಅದೇ ನಂಬಿಕೆ ನಮ್ಮಲ್ಲಿ\nಗಟ್ಟಿಯಾಗುತ್ತಾ ಹೋಗುತ್ತದೆ ಮತ್ತು ಆ ಶ್ರದ್ಧೆ ನಿಶ್ಚಲವಾಗುತ್ತದೆ. ಅದನ್ನು ಬದಲಿಸುವುದು ಬಹಳ ಕಷ್ಟ. ಈ\nಕಾರಣಕ್ಕಾಗಿ ನಾವು ದೇವರ ಬಗ್ಗೆ ತಿಳಿದುಕೊಳ್ಳಬೇಕು. ದೇವರು ಮತ್ತು ದೇವತಾ ಪರಿವಾರ ಎಂದರೆ\nಮಾನವರಂತೆ ಒಬ್ಬರನ್ನೋಬ್ಬರು ದ್ವೇಷಿಸುವ ಆಸೂಹೆ ಪಡುವ ಸಂಸ್ಕೃತಿ ಉಳ್ಳ ಒಂದು ಗುಂಪು ಎಂದು ನಾವು\nತಿಳಿದಿದ್ದರೆ ಅದು ನಮ್ಮ ಮೌಡ್ಯತೆಯ ಪರಮಾವಧಿ. ಹಿಂದೆ ಹೇಳಿದಂತೆ ಭಗವಂತ ಅನ್ನುವುದು ಏಕಶಕ್ತಿ. ಆತ\nಸದಾ ತನ್ನ ದೇವತಾ ಪರಿವಾರದೊಂದಿಗೆ ಅಭಿವ್ಯಕ್ತವಾಗುತ್ತಾನೆ. ನಾವು ಗಣಪತಿ ಅಥವಾ ಇನ್ಯಾವುದೇ\nದೇವತೆಯ ಆರಾಧನೆ ಮಾಡುವಾಗ ನಮಗೆ ಆ ಏಕಶಕ್ತಿಯ ಎಚ್ಚರ ಇದ್ದು ಮಾಡಿದರೆ ಆ ಪೂಜೆ ಮಹಾ\nಪೂಜೆಯಾಗುತ್ತದೆ. ಅದನ್ನು ಬಿಟ್ಟು ಗಣಪತಿಯೇ(ಅಥವಾ ಇನ್ಯಾವುದೇ ದೇವತೆ) ಬೇರೆ, ಅವನೊಬ್ಬನೇ ದೇವರು\nಎಂದು ತಿಳಿದು ಅದರಲ್ಲೇ ಶ್ರದ್ಧೆ ಬೆಳೆಸಿಕೊಂಡರೆ, ಆಗ ಆ ಶ್ರದ್ಧೆಯ ಬೇಲಿಯಲ್ಲಿ ನಾವು ಸಿಕ್ಕಿ ಹಾಕಿಕೊಳ್ಳುತ್ತೇವೆ.\nಇದು ಕಲ್ಲಿನ ಮೂರ್ತಿಯನ್ನು ದೇವರೆಂದು ಪೂಜಿಸಿದಂತಾಗುತ್ತದೆ. ನಿಜವಾಗಿ ನಾವು ಪೂಜಿಸುವುದು ಕಲ್ಲಿನ\nಮೂರ್ತಿಯನ್ನಲ್ಲ -ಅದರಲ್ಲಿನ ಭಗವಂತನ ಪ್ರತೀಕವನ್ನು. ಕಲ್ಲಿನ ಮೂರ್ತಿ ಕೇವಲ ದೇವತಾ ಪ್ರತೀಕ. ಸರ್ವಶಕ್ತ\nಭಗವಂತ ಆ ಮೂರ್ತಿಯೊಳಗೆ ಅಂತರ್ಗತನಾಗಿದ್ದಾನೆ. ಆದ್ದರಿಂದ ಯಾವುದೇ ದೇವತಾ ಪ್ರತೀಕವನ್ನು\nಪೂಜಿಸುವಾಗಲೂ ಕೂಡಾ “ಭಗವಂತ ಒಬ್ಬನೇ, ಆತ ಈ ದೇವತೆಯ ಪ್ರತೀಕದಲ್ಲಿ ಅಂತರ್ಗತನಾಗಿ, ತನ್ನ\nಸಮಸ್ತ ದೇವತಾ ಪರಿವಾರದ ಮೂಲಕ ನಮ್ಮನ್ನು ರಕ್ಷಿಸುತ್ತಿದ್ದಾನೆ' ಎನ್ನುವ ಅನುಸಂಧಾನ ಬಹಳ ಮುಖ್ಯ. ಈ\nಅನುಸಂಧಾನದಿಂದ ಗಣಪತಿಯನ್ನಾ ಗಲೀ, ವೀರಭದ್ರನನ್ನಾ ಗಲೀ, ಕೋಟಿ ಚನ್ನ ಯ್ಯನನ್ನಾ ಗಲಿ, ಅಥವಾ\n\nಇನ್ಯಾವುದೇ ದೇವತೆಯನ್ನು ಪೂಜಿಸಿದರೂ ಕೂಡಾ ಅದು ಪರಮಾತ್ಮ ಮೆಚ್ಚುವ ಮಹಾ ಪೂಜೆಯಾಗುತ್ತದೆ.\nನಾವು. ಮಾಡುವ ವೃತ ಅನುಷ್ಠಾನ ಕೂಡಾ ಇದೇ ರೀತಿಯಾಗಿರಬೇಕು. ಅದು ಏಕಾದಶಿಯ\nಉಪವಾಸವಾಗಿರಲೀ ಅಥವಾ ಸಂಕಷ್ಟ ಹರ ಚತುರ್ಥಿಯ ಉಪವಾಸವಾಗಿರಲೀ, ಎಲ್ಲವೂ ಕೂಡಾ ಆ ಭಗವದ್‌\nಪ್ರೀತ್ಯರ್ಥವಾಗಿರಬೇಕು. ಭಗವಂತ ಸರ್ವ ಶಬ್ದವಾಚ್ಯ-ಆದ್ದರಿಂದ ಯಾವ ಹೆಸರಿನಿಂದ ಕರೆದರೂ ಅದು\nಭಗವಂತನ ಹೆಸರು; ಭಗವಂತ ಸರ್ವ ಸಮರ್ಥ-ಆದ್ದರಿಂದ ಆತ ಕಲ್ಲಿನಲ್ಲೂ ಇರಬಹುದು ಕಂಬದಲ್ಲೂ\nಇರಬಹುದು; ಭಗವಂತ ಸರ್ವಾಂತರ್ಯಾಮಿ-ಸರ್ವ ದೇವತೆಗಳ ಅಂತರ್ಯಾಮಿಯಾಗಿದ್ದು ನಮ್ಮನ್ನು\nರಕ್ಷಿಸುವವನು ಆ ಭಗವಂತ. ಈ ಅನುಸಂಧಾನದಿಂದ ಮಾಡುವ ಭಕ್ತಿ ಶ್ರೇಷ್ಠ ಭಕ್ತಿ ಎನಿಸುತ್ತದೆ. ಇದನ್ನು ಬಿಟ್ಟು\nಅಂಧಶ್ರದ್ಧೆಯನ್ನು ಬೆಳೆಸಿಕೊಂಡರೆ ಅದೇ ನಮ್ಮಲ್ಲಿ ಗಟ್ಟಿಯಾಗಿ ನಮ್ಮನ್ನು ಅಧಃಪಾತಕ್ಕೆ ತಳ್ಳಬಹುದು!",
  "7.22": "ಸಃ ತಯಾ ಶ್ರದ್ಧಯಾ ಯುಕ್ತಃ ತಸ್ಯ ಆರಾಧನಮ್‌ ಈಹತೇ |\nಲಭತೇ ಚ ತತಃ ಕಾಮಾನ್‌ ಮಯಾ ಏವ ವಿಹಿತಾನ್‌ ಹಿ ತಾನ್‌-ಅವನು ಶ್ರದ್ಧೆಯನ್ನೇ ಆತುಕೊಂಡು ಆಯಾ\nದೇವತೆಗಳನ್ನು ಪೂಜಿಸತೊಡಗುತ್ತಾನೆ. ಅದರ ಫಲವಾಗಿ ನಾನೇ ಈಡೇರಿಸಿದ ಆಯಾ ಬಯಕೆಗಳನ್ನು\nಪಡೆಯುತ್ತಾನೆ.\n\nಮೇಲೆ ಹೇಳಿದ ಏಕಭಕ್ತಿಯನ್ನು ಪಾಲಿಸದೆ ಯಾವುದೋ ಒಂದು ದೇವತೆಯನ್ನು ಅಚಲವಾಗಿ ಪೂಜಿಸಿ ಫಲ\nಪಡೆಯವವರನ್ನು ಪ್ರಪಂಚದಲ್ಲಿ ಕಾಣುತ್ತೇವೆ. ಇಲ್ಲಿ ತಪ್ಪು ಪೂಜಾಕ್ರಮದಿಂದಲೂ ಹೇಗೆ ಫಲ ಸಿಗುತ್ತದೆ' ಎನ್ನುವ\nಪ್ರಶ್ನೆ ನಮ್ಮಲ್ಲಿ ಸಹಜವಾಗಿ ಮೂಡುತ್ತದೆ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ನೀನು ಯಾರನ್ನು ಉಪಾಸನೆ ಮಾಡಿದರೂ\nಕೊನೆಗೆ ಫಲ ಕೊಡುವವನು ನಾನೇ” ಎಂದು. ಶಾಸ್ತ್ರಗಳಲ್ಲಿ ಹೇಳುವಂತೆ \"ಸರ್ವ ದೇವ ನಮಸ್ಕಾರಃ ಕೇಶವಂ\nಪ್ರತಿಗಚ್ಛತಿ. ಯಾರನ್ನು ಪೂಜೆ ಮಾಡಿದರೂ ಅದು ಸಲ್ಲುವುದು ಅದರೊಳಗಿನ ಭಗವಂತನನ್ನೇ. ಆದರೆ\nವ್ಯತ್ಯಾಸ ಒಂದೆ-ತಿಳಿದು ಮಾಡಿದಾಗ “ಶಾಶ್ವತವಾದ ಪೂರ್ಣಫಲ', ತಿಳಿಯದೇ ಫಲಕಾಮನೆಯಿಂದ\nಮಾಡಿದಾಗ 'ಭೌತಿಕವಾದ ಅಲ್ಪಫಲ'.\n\nನಾವು. ಯಾವುದೇ ಆರಾಧ್ಯ ಮೂರ್ತಿಯನ್ನು ಪೂಜಿಸಿದರೂ ಕೂಡಾ ಆ ಆರಾಧ್ಯ ಮೂರ್ತಿಯ\nಅಂತರ್ಯಾಮಿಯಾಗಿದ್ದು ಫಲ ಕೊಡುವವನು ಭಗವಂತನೇ. ಆದರೆ “ದೇವತಾ ಅಂತರ್ಗತನಾದ ಭಗವಂತ\nಕೊಟ್ಟ' ಅನ್ನುವ ಅರಿವು ನಮಗಿರುವುದಿಲ್ಲ ಅಷ್ಟೇ. ನಮ್ಮ ಪ್ರತಿಯೊಂದು ಕ್ರಿಯೆಯಲ್ಲಿಯೂ ಈ ಎಚ್ಚರ ಬಹಳ\nಮುಖ್ಯ. ನಾವು ನಮ್ಮ ಪ್ರತಿಯೊಂದು ಅನುಸಂಧಾನವನ್ನು ಭಗವಂತನ ಪೂಜಾ ರೂಪವಾಗಿ ಮಾಡಿ\nಭವ್ಯ(divine)ವಾಗಿಸಬೇಕು. ಇಲ್ಲದಿದ್ದರೆ ಮಹಾಫಲದಿಂದ ವಂಚಿತರಾಗಿ ಯಾವುದೋ ಕ್ಷುದ್ರ ಫಲ\nನಮ್ಮದಾಗುತ್ತದೆ. [ಇಲ್ಲಿ “ಮಯೈವ ವಿಹಿತಾನ್‌ ಹಿ ತಾನ್‌” ಎಂದರೆ ನಾನೇ ದೇವತೆಯೊಳಗಿದ್ದು ಫಲವನ್ನು\n\nಕೊಡುವವನು ಎಂದರ್ಥವಾದರೆ, 'ಮಯ್ಯೆವ ವಿಹಿತಾನ್‌ ಹಿತಾನ್‌' ಎಂದರೆ “ನೀನು ಬಯಸಿದ-'ನಿನಗೆ\nಹಿತವಾದ' ಕ್ಷಣಿಕ ಫಲವನ್ನು ನನ್ನಿಂದ ಪಡೆಯುತ್ತೀಯ' ಎಂದರ್ಥ].\n",
  "7.23": "ಅಂತವತ್‌ ತು ಫಲಮ್‌ ತೇಷಾಮ್‌ ತತ್‌ ಭವತಿ ಅಲ್ಪಚೇತಸಾಮ್‌ |\nದೇವಾನ್‌ ದೇವಯಜಃ ಯಾಂತಿ ಮತ್‌ ಭಕ್ತಾಃ ಯಾಂತಿ ಮಾಮ್‌ ಅಪಿ-ಅಲ್ಪ ಮತಿಗಳಾದ ಅಂತವರ ಆ ಫಲಕ್ಕೆ\nಅಳಿವುಂಟು. ದೇವತೆಗಳನ್ನು ಪೂಜಿಸುವವರು ದೇವತೆಗಳನ್ನು ಸೇರುತ್ತಾರೆ. ನನ್ನ ಭಕ್ತರು ನನ್ನನ್ನು ಸೇರುತ್ತಾರೆ.\n\nಕೃಷ್ಣನ ಮಾತನ್ನು ಕೇಳಿದಾಗ ನಮ್ಮಲ್ಲಿ ಒಂದು ಭಾವನೆ ಮೂಡಬಹುದು: “ಯಾರು ಫಲ ಕೊಟ್ಟರೆ ನಮಗೇನು?\nನನಗೆ ನನ್ನ ಇಷ್ಟಾರ್ಥ ಸಿದ್ಧಿಯಾದರೆ ಸಾಕು” ಎಂದು. ಅದಕ್ಕಾಗಿ ಈ ಶ್ಲೋಕದಲ್ಲಿ ಕೃಷ್ಣ ಎಚ್ಚರಿಕೆಯ\nನುಡಿಯನ್ನಾಡುತ್ತಾನೆ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ಅಂತವತ್ತು ಫಲಂ ತೇಷಾಂ ತದ್‌ ಭವತ್ಯಲ್ಪಚೇತಸಾಮ್‌” ಎಂದು.\nಅಂದರೆ ಯಾವುದೋ ಒಂದು ಕ್ಷುದ್ರ ಫಲ ಸಿಕ್ಕಿತು ಎಂದು ಹಿಗ್ಗುವವರು ಅಲ್ಪ್ಬಮತಿಗಳು. ಈ ರೀತಿಯಾಗಿ ಸಿಗುವ\nಫಲ ಎಂದೂ ಶಾಶ್ವತ ಅಲ್ಲ, ಅದು ಕ್ಷಣಿಕ. “ನೀವು ಯಾವ ದೇವತೆಯನ್ನು ಪೂಜಿಸುತ್ತೀರೋ ಆ ದೇವತೆಯನ್ನು\nಸೇರುತ್ತೀರೇ ಹೊರತು ಮೋಕ್ಷವನ್ನಲ್ಲ” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಯಾವ ದೇವತೆಗಳೂ ಕೂಡಾ ಅನಂತ ಕಾಲದ ತನಕ\nನಮ್ಮನ್ನು ಅವರ ಲೋಕದಲ್ಲಿ ಇರಗೊಡುವುದಿಲ್ಲ. ಆದ್ದರಿಂದ ನಾವು ಮಾಡಿದ ಕರ್ಮದ ಅವಧಿ ಮುಗಿದಾಕ್ಷಣ\nಮರಳಿ ಈ ಮೃತ್ಯುಲೋಕಕ್ಕೆ ಬರಬೇಕಾಗುತ್ತದೆ. ಈ ಕಾರಣದಿಂದ ಭಗವಂತನ ಅರಿವಿಲ್ಲದ ಕೇವಲ ದೇವತಾ\nಉಪಾಸನೆ ಶಾಶ್ವತ ಮೋಕ್ಷವನ್ನು ಕೊಡಲಾರದು.\n\nಭಗವಂತನಲ್ಲಿ ಮನವಿಟ್ಟು, ಏಕಭಕ್ತಿಯಿಂದ ಭಗವಂತನನ್ನು ಭಜಿಸಿದರೆ ಆಗ 'ತದ್ಧಾಮಂ ಪರಮಂ ಮಮ'”-\nಎಲ್ಲಿಂದ ಎಂದೂ ಮರಳಿ ಬರಬೇಕಾಗಿಲ್ಲವೋ ಅಂತಹ ಶಾಶ್ವತವಾದ ಮೋಕ್ಷವನ್ನು ಪಡೆಯುತ್ತಾರೆ.\nಭಗವಂತನನ್ನು ಪ್ರೀತಿಸುವುದರಿಂದ ಯಥಾರ್ಥ ಜ್ಞಾನ ಸಿದ್ಧಿಯಾಗುತ್ತದೆ. ಇದರಿಂದ ಎಂದೆಂದೂ ದುಃಖವಿಲ್ಲದ\nಭಗವದ್‌ ಪ್ರಾಪ್ತಿ ರೂಪವಾದ ಮೋಕ್ಷವನ್ನು ಪಡೆಯುಬಹುದು.\n\nಇಲ್ಲಿ ಕೆಲವರಿಗೆ ಒಂದು ಗೊಂದಲವಾಗಬಹುದು. “ದೇವರು ಏಕೆ ಹೊಗಳುವಿಕೆಯನ್ನು ಇಷ್ಟಪಡುತ್ತಾನೆ? ಆತ ಏಕೆ\nತನ್ನನ್ನು ಹೊಗಳುವವರನ್ನು ಮಾತ್ರ ಉದ್ಧರಿಸಿ ಉಳಿದವರನ್ನು ಉದ್ಭರಿಸುವುದಿಲ್ಲ?” ಎಂದು. ದೇವರು\nಪ್ರೀತಿಸುವುದು ಹೊಗಳಿಕೆಯನ್ನಲ್ಲ-ಸತ್ಯವನ್ನು. ವಿಷ್ಣು ಸಹಸ್ರನಾಮದಲ್ಲಿ ಬರುವ ಸಾವಿರ ನಾಮದಲ್ಲಿ ದೇವರು\nಅಂದರೆ ಏನು ಆತನ ಮಹಾತ್ಮೆ ಏನು(etymologically)) ಎನ್ನುವ ಸತ್ಯ ಅಡಗಿದೆ. ಭಗವಂತ ಯಾರು\nಸತ್ಯವನ್ನು ತಿಳಿಯುತ್ತಾರೋ ಅವರನ್ನು ಪ್ರೀತಿಸುತ್ತಾನೆ. ಆತನಿಗೆ ವೈಯಕ್ತಿಕ ಇಷ್ಟಾನಿಷ್ಟವಿಲ್ಲ. ಆತ ಇಷ್ಟ\nಪಡುವುದು ಯಥಾರ್ಥ ಜ್ಞಾನವನ್ನು. ಯಥಾರ್ಥ ಜ್ಞಾನ-ಭಕ್ತಿ ರೂಪದಲ್ಲಿದೆ. ನಿಜವಾದ ಭಕ್ತಿ-ಯಥಾರ್ಥ\nಜ್ಞಾನದಲ್ಲಿದೆ. ಯಥಾರ್ಥದ ಅರಿವು ಭಗವಂತನಿಗೆ ಇಷ್ಟ ಮತ್ತು ಇದು ಮೋಕ್ಷವನ್ನು ತಲುಪಲು ಬೇಕಾದ\nಅರ್ಹತೆ. ಆದ್ದರಿಂದ ಭಗವಂತ ತನ್ನನ್ನು ಹೊಗಳುವವರನ್ನು ಉದ್ಧರಿಸುವುದಲ್ಲ. ಆತ ಯಥಾರ್ಥವನ್ನು\nತಿಳಿದವರನ್ನು ಉದ್ಧರಿಸುತ್ತಾನೆ ಮತ್ತು ಅರ್ಹತೆ ಉಳ್ಳವರಿಗೆ ಮೋಕ್ಷ ಕರುಣಿಸುತ್ತಾನೆ.\n\n“ಶಾಶ್ವತ ಫಲವನ್ನು ಕೊಡತಕ್ಕಂತಹ ಅಂತರ್ಯಾಮಿಯ ಉಪಾಸನೆಯಲ್ಲಿ ಗಟ್ಟಿಯಾಗಿ-ಮೋಕ್ಷವನ್ನು ಪಡೆ”\nಎನ್ನುವುದು ಇಲ್ಲಿ ಕೃಷ್ಣನ ಸಂದೇಶ.\n\nಭಗವಂತನನ್ನು ತಿಳಿಯಬೇಕು ಎಂದು ಭಕ್ತಿ ಮತ್ತು ಜ್ಞಾನ ಮಾರ್ಗದಲ್ಲಿ ಸಾಗಿದವರಿಗೂ ಕೂಡಾ ಭಗವಂತನನ್ನು\nತಿಳಿಯುವುದು ಎಷ್ಟು ಕಷ್ಟ ಎನ್ನುವುದನ್ನು ಕೃಷ್ಣ ಈ ಅಧ್ಯಾಯದಲ್ಲಿ ಇನ್ನೂ ವಿವರಿಸುತ್ತಾನೆ.\n",
  "7.24": "ಅವ್ಯಕ್ತಮ್‌ ವ್ಯಕ್ತಿಮ್‌ ಅಪನ್ನಮ್‌ ಮನ್ಯಂತೇ ಮಾಮ್‌ ಅಬುದ್ಧಯಃ |\n\nಪರಮ್‌ ಭಾವಮ್‌ ಅಜಾನಂತಃ ಮಮ ಅವ್ಯಯಮ್‌ ಅನುತ್ತಮಮ್‌-ಅಳಿವಿರದ, ಮಿಗಿಲಿರದ ನನ್ನ ಮಹಿಮೆಯ\nಹಿರಿಮೆಯನ್ನರಿಯದ ತಿಳಿಗೇಡಿಗಳು ದೇಹದಿಂದ ಹುಟ್ಟಿಬರದ ನನ್ನನ್ನು ಹುಟ್ಟಿಬಂದೆ ಎಂದು [ಭಗವಂತನೇ\nಜೀವಭಾವ ಪಡೆದನೆಂದು ] ತಿಳಿದುಬಿಡುತ್ತಾರೆ.\n\nಸಾಮಾನ್ಯವಾಗಿ ಭಗವಂತನ ಬಗೆಗೆ ಸರಿಯಾದ ತಿಳುವಳಿಕೆ ಗಳಿಸುವುದು ಕಷ್ಟ. ಆದರೆ ತಪ್ಪು ಗ್ರಹಿಕೆ ಸುಲಭ.\nಇಲ್ಲಿ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ನಾನು ವಸ್ತುತಃ ಅವ್ಯಕ್ತ” ಎಂದು. ಜೀವ ವ್ಯಕ್ತ ಆಗುವುದು ಅದಕ್ಕೆ ಪಾಂಚಭೌತಿಕ ಶರೀರ\nಬಂದಾಗ. ಆದ್ದರಿಂದ ಸ್ಥೂಲವಾದ ಶರೀರವುಳ್ಳದ್ದನ್ನು ವ್ಯಕ್ತ ಎನ್ನುತ್ತಾರೆ. ಭಗವಂತನಿಗೆ ಒಂದುದಿನ\nನಾಶವಾಗುವ ಪಾಂಚಭೌತಿಕ ಶರೀರ ಇಲ್ಲ- ಆತ ಸರ್ವದಾ ಅವ್ಯಕ್ತ. ಇಂತಹ ಅವ್ಯಕ್ತ ಭಗವಂತ ತನ್ನ\nಅವತಾರದಲ್ಲಿ ತನ್ನ ಸ್ವಂತ ಇಚ್ಛೆಯಿಂದ ಒಂದು ರೂಪದಲ್ಲಿ ಎಲ್ಲರಿಗೂ ಕಾಣಿಸಿಕೊಳ್ಳುತ್ತಾನೆ. ಶಾಸ್ತ್ರೀಯವಾಗಿ\nಭಗವಂತನ ಸ್ವರೂಪದ ಅರಿವಿಲ್ಲದ ಜನ ತಮಗೆ ಕಾಣುವ ಅವತಾರರೂಪಿ ಭಗವಂತನಿಗೆ ತಮ್ಮಂತೆ\nಪಾಂಚಭೌತಿಕ ಶರೀರವಿದೆ ಮತ್ತು ಭಗವಂತ ಒಂದು ದಿನ ದೇಹತ್ಯಾಗ ಮಾಡುತ್ತಾನೆ ಎಂದು ತಿಳಿಯುತ್ತಾರೆ.\nವ್ಯಕ್ತವಾದ, ಸ್ಥೂಲವಾದ, ನಶ್ವರವಾದ, ಪ್ರಾಕೃತವಾದ ಶರೀರ ಇಲ್ಲದ ಭಗವಂತನನ್ನು ಅಂತಹ ಸ್ಥೂಲವಾದ\nಶರೀರದೊಳಗೆ ಬದ್ಧನಾಗಿರುವವನು. ಎನ್ನುವ ಅರ್ಥದಲ್ಲಿ ಅವರು ತಿಳಿದುಕೊಳ್ಳುತ್ತಾರೆ. “ಹೀಗೆ\nತಿಳಿದುಕೊಳ್ಳುವವರು ಬುದ್ಧಿಶೂನ್ಯರು” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.",
  "7.25": "ನ ಅಹಮ್‌ ಪ್ರಕಾಶಃ ಸರ್ವಸ್ಯ ಯೋಗ ಮಾಯಾ ಸಮಾವೃತಃ |\n\nಮೂಢಃ ಅಯಮ್‌ ನ ಅಭಿಜಾನಾತಿ ಲೋಕಃ ಮಾಮ್‌ ಅಜಮ್‌ ಅವ್ಯಯಮ್‌-ನನ್ನ ಸಾಮರ್ಥ್ಯ ಮತ್ತು ಪ್ರಕೃತಿಯ\nಮಾಯೆಯಿಂದ ಮುಚ್ಚಿಕೊಂಡಿರುವ ನಾನು ಎಲ್ಲರಿಗೂ ಬಯಲಾಗಲಾರೆ. ಹುಟ್ಟಿರದ ಸಾವಿರದ ನನ್ನನ್ನು ಈ\nತಿಳಿಗೇಡಿ ಮಂದಿ ತಿಳಿಯಲಾರರು.\n\nಭಗವಂತ ಎಲ್ಲರಿಗೂ ಕಾಣಿಸಿಕೊಳ್ಳುವುದಿಲ್ಲ. ಆತನ ಅನಂತ ಗುಣದ ಸ್ಪಷ್ಟ ಚಿತ್ರ ಯಾರಿಗೂ ಬರುವುದು\nಸಾಧ್ಯವಿಲ್ಲ. ಮನುಷ್ಯನ ಚಿಂತನೆಗೆ ಒಂದು ಮಿತಿ ಇದೆ, ಆದರೆ ಭಗವಂತ ಆ ಮಿತಿಯ ಒಳಗಿಲ್ಲ. ಆದ್ದರಿಂದ ನಮ್ಮ\nಬುದ್ಧಿ ಆತನ ಅನಂತವಾದ ಜ್ಞಾನವನ್ನು, ಅನಂತವಾದ ಶಕ್ತಿಯನ್ನು, ಆನಂತ ರೂಪವನ್ನು ಗ್ರಹಿಸಲಾರದು.\nನಾವು ಇಚ್ಛೆಪಟ್ಟಾಗ ಭಗವಂತ ಕಾಣುವುದಿಲ್ಲ. ಆದರೆ ಕಾಲ ಪಕ್ಚವಾದಾಗ ತನ್ನ ಇಚ್ಛೆಯಂತೆ ಭಗವಂತ\nಜ್ಞಾನಾನಂದ ಸ್ವರೂಪವಾದ ಮನಸ್ಸು ಮತ್ತು ಜ್ಞಾನಾನಂದ ಸ್ವರೂಪವಾದ ಇಂದ್ರಿಯಗಳಿಗೆ ಯಥಾಶಕ್ತಿ\nಗೋಚರವಾಗಬಲ್ಲ. ಈ ಲೋಕದಲ್ಲಿ ಅಜ್ಞಾನದ ಮೋಹಕ್ಕೆ ಒಳಗಾದ ಜೀವಜಾತ ಎಂದೂ ಭಗವಂತನನ್ನು\nಗ್ರಹಿಸಲಾರದು. ಜೀವನಿಗೂ ಮತ್ತು ಭಗವಂತನಿಗೂ ನಡುವೆ ಇರುವ ಅಜ್ಞಾನವೆಂಬ ಮಾಯಾ ಪರದೆಯಿಂದಾಗಿ\nಭಗವಂತ ನಮಗೆ ಕಾಣುವುದಿಲ್ಲ.",
  "7.26": "ವೇದ ಅಹಮ್‌ ಸಮತೀತಾನಿ ವರ್ತಮಾನಾನಿ ಚ ಅರ್ಜುನ ।\nಭವಿಷ್ಯಾಣಿ ಚ ಭೂತಾನಿ ಮಾಮ್‌ ತು ವೇದ ನ ಕಶ್ಚನ- ಅರ್ಜುನಾ, ನಾನು ತಿಳಿದಿದ್ದೇನೆ-ಹಿಂದಿದ್ದ ಜೀವಿಗಳನ್ನು ಸ;\nಈಗಿರುವವರನ್ನು, ಮುಂದೆ ಬರುವವರನ್ನು ಕೂಡಾ. ನನ್ನನ್ನು ಮಾತ್ರ ಯಾರೂ ತಿಳಿದಿಲ್ಲ.\n\nಜೀವ ಮತ್ತು ಭಗವಂತನ ನಡುವಿನ ವ್ಯತ್ಯಾಸವನ್ನು ಬಹಳ ಸ್ಪಷ್ಟವಾಗಿ ವಿವರಿಸುತ್ತಾ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ಹಿಂದೆ\nಆಗಿ ಹೋದ ಭೂತಗಳು, ಈಗ ಇರುವ ಭೂತಗಳು, ಮತ್ತು ಮುಂದೆ ಬರಲಿರುವ ಭೂತಗಳು ಈ ಎಲ್ಲವನ್ನೂ\nನಾನು ತಿಳಿದಿದಿದ್ದೇನೆ” ಎಂದು. ಇಲ್ಲಿ ಭೂತ ಎನ್ನುವ ಪದಕ್ಕೆ ಅನೇಕ ಅರ್ಥವಿದೆ. ಪಂಚಭೂತಗಳು, ಅದರಿಂದ\nನಿರ್ಮಾಣವಾದ ಬ್ರಹ್ಮಾಂಡ, ಅದರಿಂದ ರೂಪುಗೊಂಡ ಸಮಸ್ತ ವಸ್ತುಗಳು ಮತ್ತು ಸಮಸ್ತ ಜೀವಜಾತಗಳು\nಎಲ್ಲವೂ ಭೂತಗಳು. ಈ ಹಿಂದೆ ಸೃಷ್ಟಿಯಾದ ಅನಂತ ಬ್ರಹ್ಮಾಂಡ, ಈಗಿರುವ ಬ್ರಹ್ಮಾಂಡ, ಮುಂದೆ\nಸೃಷ್ಟಿಯಾಗಲಿರುವ ಅನಂತ ಬ್ರಹ್ಮಾಂಡ, ಹಿಂದೆ ಇದ್ದ ಅನಂತ ಜೀವಜಾತಗಳು, ಈಗಿರುವ ಅನಂತ\nಜೀವಜಾತಗಳು ಮತ್ತು ಮುಂದೆ ಸೃಷ್ಟಿಯಾಗಲಿರುವ ಅನಂತ ಜೀವಜಾತಗಳನ್ನು ತಿಳಿದವನು ಆ ಅನಂತಕೋಟಿ\nಬ್ರಹ್ಮಾಂಡ ನಾಯಕ ಭಗವಂತನೊಬ್ಬನೆ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ಮಾಮ್‌ ತು ವೇದ ನ ಕಶ್ಚನ” ಎಂದು. ಅಂದರೆ\n\"ನನ್ನನ್ನು ಬಿಟ್ಟು ಇನ್ಯಾರೂ ಇದನ್ನು ಪೂರ್ಣವಾಗಿ ತಿಳಿದಿಲ್ಲ'. ಭಗವಂತನನ್ನು ಪೂರ್ಣವಾಗಿ ತಿಳಿದವರಿಲ್ಲ ಹಾಗೂ\nತಿಳಿಯುವುದು ಸಾಧ್ಯವಿಲ್ಲ. ಆತ ಸ್ವತಂತ್ರ, ಪೂರ್ಣ ಮತ್ತು ನಿತ್ಯಸತ್ಯ. ಜೀವ ಅಪೂರ್ಣ, ಅಸ್ವತಂತ್ರ ಮತ್ತು\nಅನಿತ್ಯಸತ್ಯ.\n\nಭಗವಂತನನ್ನು ಪೂರ್ಣವಾಗಿ ತಿಳಿಯುವುದು ಅಸಾಧ್ಯ. ಆದರೆ ತಮ್ಮ ಯಥಾಶಕ್ತಿ ಅರಿಯಲು ಎಲ್ಲರಿಗೂ ಏಕೆ\nಸಾಧ್ಯವಾಗುವುದಿಲ್ಲ ಎನ್ನುವುದನ್ನು ಕೃಷ್ಣ ಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ವಿವರಿಸುತ್ತಾನೆ.\n",
  "7.27": "ಇಚ್ಛಾ ದ್ವೇಷ ಸಮುತ್ಥೇನ ದ್ವಂದ್ವ ಮೋಹೇನ ಭಾರತ ।\n\nಸರ್ವ ಭೂತಾನಿ ಸಮ್ಮೋಹಮ್‌ ಸರ್ಗೇ ಯಾಂತಿ ಪರಂತಪ-ಓ ಅರಿಗಳನ್ನು ತರಿದವನೇ, ಭರತ ವಂಶದ-\nಕುಡಿಯೇ, ಒಲವು-ಹಗೆತನಗಳಿಂದ ಹುಟ್ಟಿದ ಸುಖ-ದುಃಖ ಮುಂತಾದ ದ್ವಂದ್ವಗಳ [ಜೀವೇಶ್ವರರು ಮುಂತಾದ\nದ್ವಂದ್ವಗಳ] ತಪ್ಪು ಗ್ರಹಿಕೆಯಿಂದ ಎಲ್ಲಾ ಜೀವಿಗಳೂ ಹುಟ್ಟಿನಿಂದಲೇ ಸುಳ್ಳಿನ ಕೆಟ್ಟದಾರಿ ಹಿಡಿದಿವೆ.\n\nನಾವು ಹುಟ್ಟು ವಾಗಲೇ ಹುಟ್ಟಿ ನ ಜೊತೆಗೆ \"ಇಚ್ಛಾ-ದ್ವೇಷ' ಸೇರಿಸಿಕೊಂಡು ಹುಟ್ಟು ತ್ತೇವೆ. ಶರೀರ ಬೆಳೆದಂತೆ ಅದು\nಬೆಳೆಯುತ್ತಾ ಹೋಗುತ್ತದೆ. ಇದರಿಂದ ಇಬ್ಬಂದಿತನ(ದ್ವಂದ)ದದ ಗೊಂದಲ. ಯಾವುದರಿಂದ ಸುಖ,\nಯಾವುದರಿಂದ ದುಃಖ ಎಂದು ಗೊತ್ತಿಲ್ಲದೇ ದುಃಖವನ್ನೇ ಸುಖ ಎಂದು ತಿಳಿದು ಅದರ ಬೆನ್ನು ಹತ್ತಿ ಕೊನೆಗೆ ದುಃಖ\nಬಂದಾಗ ಅಯ್ಯೋ ಎನ್ನು ತ್ತೇವೆ. ಸುಳ್ಳನ್ನೇ ಸತ್ಯ ಎಂದು ನಂಬುವುದು, ಜ್ಞಾನ-ಅಜ್ಞಾನದ ಗೊಂದಲ, ಸತ್ಯ-\nಅಸತ್ಯದ ಗೊಂದಲ, ಹೀಗೆ ದ್ವಂದ್ವ ಮೋಹಕ್ಕೆ ಒಳಗಾದವರನ್ನು ತಿದ್ದುವುದು ಬಹಳ ಕಷ್ಟ. ಇದು ಬರಿಯ ಮೋಹ\nಮಾತ್ರವಲ್ಲ, ಇದೊಂದು ಸಮ್ಮೋಹ! ನಾನು ತಿಳಿದಿರುವುದೇ ಸರಿ ಎನ್ನುವ ಹಠ, ತನ್ನದೇ ಸರಿ ಎನ್ನುವ ಆಗ್ರಹ.\nಇದರಿಂದ ಮನುಷ್ಯ ಸತ್ಯವನ್ನು ಅರಿಯದೆ ಅಜ್ಞಾನಿಯಾಗುತ್ತಾನೆ. ಹೀಗೆ ಅಜ್ಞಾನದಿಂದ ಮೋಹ, ಮೋಹದಿಂದ\nಸಮ್ಮೋಹ. ಗೊತ್ತಿಲ್ಲದೇ ಇರುವುದನ್ನು ತಿಳಿದುಕೊಳ್ಳಲು ಪ್ರಯತ್ನಿಸದೇ ಇದ್ದಾಗ ಅದರಿಂದ ವಿಪರೀತ ಜ್ಞಾನ-\nನಂತರ ನಾನು ನಂಬಿದ್ದೇ ಸರಿ ಎನ್ನು ವ ಆಗ್ರಹ. ಇದು ಸಾಮಾನ್ಯವಾಗಿ ನಾವು ಕಾಣುವ ಮನುಷ್ಯನ ದೌರ್ಬಲ್ಯ.\nಈ ಪ್ರಪಂಚದಲ್ಲಿ ಪ್ರತಿಯೊಬ್ಬ ದಡ್ಡನೂ ಕೂಡಾ ತಾನು ಎಲ್ಲರಿಗಿಂತ ಬುದ್ಧಿವಂತ ಎಂದು ತಿಳಿದಿರುತ್ತಾನೆ!\nಆದ್ದರಿಂದ ಇಡೀ ಜಗತ್ತಿನ ವ್ಯವಹಾರವನ್ನು ತನ್ನ ಬುದ್ಧಿಯ ಮಾನದಂಡದಿಂದ ಅಳೆದು ದಾರಿತಪ್ಪುತ್ತಾನೆ.\nಇದನ್ನು ಮಹಾಭಾರತದಲ್ಲಿ ಹೀಗೆ ಹೇಳಿದ್ದಾರೆ: “ಸರ್ವೋಹಿ ಮನ್ಯತೇ ಲೋಕ ಆತ್ಮಾನಂ ಬುದ್ಧಿಮತ್ತರಂ”\nಎಂದು. ತಾನು ಬುದ್ಧಿವಂತ, ನನ್ನ ತೀರ್ಮಾನವೇ ಸರಿ, ಉಳಿದವರಿಗೆ ನನ್ನಷ್ಟು ತಿಳುವಳಿಕೆ ಇಲ್ಲ ಅನ್ನುವ ತಪ್ಪು\nಕಲ್ಪನೆಯಿಂದ ಮನುಷ್ಯ ಸಮ್ಮೋಹದತ್ತ ಸಾಗುತ್ತಾನೆ. ಈ ಅಪಾಯದಿಂದ ಯಾರು ಹೇಗೆ ಪಾರಾಗುತ್ತಾರೆ\nಎನ್ನುವುದನ್ನು ಮುಂದಿನ ಶ್ಲೋಕ ವಿವರಿಸುತ್ತದೆ.\n\nಇಲ್ಲಿ ಕೃಷ್ಣ ಅರ್ಜುನನನ್ನು 'ಭಾರತ' ಮತ್ತು “ಪರಂತಪ' ಎನ್ನುವ ವಿಶೇಷಣಗಳಿಂದ ಸಂಬೋಧಿಸಿದ್ದಾನೆ.\nಭಗವಂತನ ಅರಿವು ಪಡೆಯಬೇಕಾದರೆ ನಾವು ಭಾರತ-ಪರಂತಪರಾಗಬೇಕು. ಬೆಳಕಿನ ದಾರಿಯಲ್ಲಿ ರಥನಾಗಿ\nಸಾಗಿ(ಭಾರತ), ಪರತತ್ವದ ನಿರಂತರ ಚಿಂತನೆ(ಪರಂತಪ) ಮಾಡಿದಾಗ ಮಾತ್ರ ನಮಗೆ ಭಗವಂತನ ಛಾಯೆ\nತಿಳಿದೀತು ಎನ್ನುವುದು ಈ ವಿಶೇಷಣದ ಅರ್ಥವಿಶೇಷ.\n",
  "7.28": "ಯೇಷಾಮ್‌ ತು ಅಂತಗತಮ್‌ ಪಾಪಮ್‌ ಜನಾನಾಮ್‌ ಪುಣ್ಯಕರ್ಮಣಾಮ್‌ |\nತೇ ದ್ವಂದ್ವ ಮೋಹ ನಿರ್ಮುಕ್ತಾಃ ಭಜಂತೇ ಮಾಮ್‌ ದೃಢವ್ರತಾಃ-ಪುಣ್ಯವಂತರಾದ ಯಾವ ಜನರ ಪಾಪ\nಕೊನೆಗೊಂಡಿದೆಯೋ ಅವರು ದ್ವಂದ್ವಗಳ ತಪ್ಪರಿವಿನಿಂದ ಕಳಚಿಕೊಂಡು ನಿಷ್ಠೆಯ ನೇಮದಿಂದ ನನ್ನನ್ನು\nಸೇವಿಸುತ್ತಾರೆ.\nಹಿಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ಕೃಷ್ಣ ದ್ವಂದ್ವ ಮೋಹದ ಬಗ್ಗೆ ಹೇಳಿದ. ಇದಕ್ಕೆ ಮೂಲಭೂತವಾಗಿ ಎರಡು ಕಾರಣ. ಒಂದು\nಜೀವಸ್ವರೂಪ(ಉದಾ: ದುರ್ಯೋಧನ, ಶಕುನಿ). ಇನ್ನೊಂದು ಪ್ರರಾಬ್ಧ ಕರ್ಮ(ಉದಾ: ಕರ್ಣ, ಅಜಾಮಿಳ,\nಪಿಂಗಳೆ)ು. ಜೀವ ಸ್ವರೂಪವೇ ಇಂತಹ ಗತಿಯಲ್ಲಿದ್ದರೆ ಅದಕ್ಕೆ ಯಾವುದೇ ಪರಿಹಾರ ಮಾರ್ಗವಿಲ್ಲ. ಆದರೆ\nಯಾವುದೋ ಕಾರಣದಿಂದ ಕೆಟ್ಟ ದಾರಿಯಲ್ಲಿ ಸಾಗುವ ಸಾತ್ವಿಕ ಜೀವಕ್ಕೆ ಜ್ಞಾನದ ಮಾರ್ಗವಿದೆ. ಯಾವುದೋ\nಒಂದು ದುರಂತದಿಂದ ಕೆಲವೊಮ್ಮೆ ಅಪರೋಕ್ಷ ಜ್ಞಾನಿಗಳೂ ದಾರಿ ತಪ್ಪುತ್ತಾರೆ. ಇಂತವರ ಪಾಪ ಕರ್ಮ\nತೊಳೆದು ಹೋಗುವ ತನಕ ಅವರು ಸರಿ ದಾರಿಗೆ ಬರಲಾಗುವುದಿಲ್ಲ. ಆದರೆ ಕೆಲವೊಮ್ಮೆ ಜೀವನದಲ್ಲಿ ನಡೆಯುವ\nಕೆಲವು ದುರಂತ ಅಥವಾ ಆಘಾತ ಇಂತವರನ್ನು ಮರಳಿ ಸತ್ಯದ ಮಾರ್ಗಕ್ಕೆ ಕರೆತರುತ್ತದೆ. ಇಂತಹ\nಸಂದರ್ಭದಲ್ಲಿ ಅವರಿಗೆ ತಮ್ಮ ತಪ್ಪಿನ ಅರಿವಾಗಿ ಪಶ್ಚಾತ್ತಾಪ ಭಾವನೆಯಿಂದ ದೇವರಲ್ಲಿ ಅಗಾಧವಾದ ಭಕ್ತಿ\nಮೂಡುತ್ತದೆ.\nಪಶ್ಚಾತ್ತಾಪಕ್ಕಿಂತ ಶ್ರೇಷ್ಠವಾದ ಪ್ರಾಯಶ್ಚಿತ್ತ ಇನ್ನೊಂದಿಲ್ಲ. ಎಂತಹ ಪಾತಕವನ್ನೂ ಕೂಡಾ ಪಶ್ಚಾತ್ತಾಪದಿಂದ\nತಿದ್ದಿಕೊಳ್ಳಬಹುದು. ನಾವು ನಮ್ಮ ಜೀವನದಲ್ಲಿ ನಮಗೆ ತಿಳಿದೋ ತಿಳಿಯದೆಯೋ ತಪ್ಪು ಮಾಡುತ್ತಿರುತ್ತೇವೆ.\nಮಾನಸಿಕವಾಗಿ, ದೈಹಿಕವಾಗಿ, ವಾಚಕವಾಗಿ ನಮಗೆ ತಿಳಿಯದೆಯೇ ನಮ್ಮಿಂದ ತಪ್ಪು ನಡೆಯುತ್ತಿರುತ್ತದೆ.\nಆದರೆ ತಪ್ಪಿನ ಅರಿವಾದಾಗ ಹೃದಯದಿಂದ ಮೂಡುವ ಪಶ್ಚಾತ್ತಾಪ ಇಂತಹ ತಪ್ಪಿಗೆ ಪ್ರಾಯಶ್ಚಿತ್ತ. ವೈದಿಕ\nಸಂಪ್ರದಾಯದಲ್ಲಿ ದೇವತಾರ್ಚನೆಯ ನಂತರ ನಮಸ್ಕಾರ ಮಾಡುವಾಗ ಹೇಳಿಕೊಳ್ಳುವ ಶ್ಲೋಕ ಒಂದಿದೆ:\n\nಪಾಪೋ$ಹಂ ಪಾಪಕರ್ಮಾಹಂ ಪಾಪಾತ್ಮಾ ಪಾಪಸಂಭವ |\n\nತ್ರಾಹಿ ಮಾ ಕೃಪಯಾ ದೇವ ಸರ್ವಪಾಪಹರೋ ಭವ ॥\n\nಅನ್ಯಥಾ ಶರಣಂ ನಾಸ್ತಿ ತ್ವಮೇವ ಶರಣಂ ಮಮ |\n\nತಸ್ಮಾತ್‌ ಕಾರುಣ್ಯಭಾವೇನ ರಕ್ಷ ಮಾಂ ಜಗದೀಶ್ವರ |\nಇಲ್ಲಿ ನಾವು ಆ ಭಗವಂತನಲ್ಲಿ “ನಾನು ತಿಳಿದೋ ತಿಳಿಯದೆಯೋ ಮಾಡಿದ ತಪ್ಪನ್ನು ಕ್ಷಮಿಸು” ಎಂದು\nಬೇಡುತ್ತೇವೆ. “ನಾನು ಹುಟ್ಟಿನಿಂದ ಪಾಪವನ್ನು ಹೊತ್ತು ಬಂದಿದ್ದೇನೆ, ಅದರಿಂದ ತಪ್ಪು ಮಾಡುತ್ತಿದ್ದೇನೆ,\nಆದ್ದರಿಂದ ನನ್ನನ್ನು ಕ್ಷಮಿಸಿ ಈ ಪಾಪದಿಂದ ನನ್ನನ್ನು ಪಾರು ಮಾಡು” ಎಂದು ದೇವರಲ್ಲಿ ಶರಣಾಗುವುದು ಈ\nಶ್ಲೋಕದ ಮೂಲಕ ನಾವು ದೇವರಲ್ಲಿ ಮಾಡುವ ಪ್ರಾರ್ಥನೆ. ಇಲ್ಲಿ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ. “ತೇ ದ್ವಂದ್ವ\nಮೋಹನಿರ್ಮುಕ್ತಾ ಭಜಂತೇ ಮಾಂ ದೃಢವ್ರತಾಃ” ಎಂದು. ಅಂದರೆ ಒಮ್ಮೆ ಇಂತಹ ಪಾಪ ಕರ್ಮದಿಂದ ಆಚೆ\nಬಂದರೆ, ಎಲ್ಲಾ ದ್ವಂದ್ವ ಮೋಹಗಳೂ ಪರಿಹಾರವಾಗಿ ಭಗವಂತನಲ್ಲಿ ಗಾಢವಾದ ಭಕ್ತಿ ನೆಲೆ ನಿಲ್ಲುತ್ತದೆ. ಈ ರೀತಿ\nಪಾಪದ ಅರಿವಾಗಿ ಪಶ್ಚಾತ್ತಾಪದಿಂದ ಭಗವಂತನೆಡೆಗೆ ತಿರುಗಿದವರು ಬಹಳ ಬೇಗ ಭಗವಂತನ ದಾರಿಯಲ್ಲಿ\n\nಸಾಗುತ್ತಾರೆ.\n",
  "7.29": "ಜರಾ ಮರಣ ಮೋಕ್ಷಾಯ ಮಾಮ್‌ ಆಶ್ರಿತ್ಯ ಯತಂತಿ ಯೇ |\n\nತೇ ಬ್ರಹ್ಮ ತತ್‌ ವಿದುಃ ಕೃತ್ಸ್ನ ಮ್‌ ಅಧ್ಯಾತ್ಮ; ಮ್‌ ಕರ್ಮ ಚ ಅಖಿಲಮ್‌-ಮುಪ್ಪು-ಸ -ಸಾವುಗಳಿಂದ ಪಾರಾಗಲೆಂದು\nನನ್ನನ್ನು ಮೊರೆಹೊಕ್ಕು ಸಾಧನೆಗೆಳಸುವವರು ಆ. “ಬ್ರಹ್ಮತತ್ವ”ವನ್ನು ತಿಳಿಯಬಲ್ಲರು; ಸಮಗ್ರವಾದ\n\"ಅಧ್ಯಾತ್ಮ' 'ವನ್ನು ಮತ್ತು ಎಲ್ಲಾ “ಕರ್ಮ' ವನ್ನು ಕೂಡಾ.\n\nಭಗವಂತನೆಡೆಗೆ ತಿರುಗಿದವರು ಮುಪ್ಪು-ಸಾವಿನಿಂದ ಪಾರಾಗುವುದಕ್ಕೋಸ್ಕರ, ಈ ಸಂಸಾರ ಬಂಧದಿಂದ\nಬಿಡುಗಡೆ ಬಯಸಿ ಭಗವಂತನ ಮೊರೆ ಹೋಗುತ್ತಾರೆ ಮತ್ತು ಸಾಧನೆ ಮಾಡುತ್ತಾರೆ. ಸಾಮಾನ್ಯವಾಗಿ ಏನನ್ನೂ\nಬಯಸದೇ ಇರುವುದು ಶ್ರೇಷ್ಠ, ಆದರೆ ಬಯಸುವುದೇ ಜೀವನ ಧರ್ಮವಾಗಿದ್ದಾಗ ಇನ್ನೇನನ್ನೊ ೀ ಬಯಸದೆ\nಮೋಕ್ಷವನ್ನು ಬಯಸುವುದು ಶ್ರೇಷ್ಠ. ಈ ಶ್ಲೋಕದಲ್ಲಿ ಕೃಷ್ಣ ಮೋಕ್ಷಕ್ಕೆ ಹೋಗುವ ಸಾಧಕನ ಪ್ರಯತ್ನ ಏನು,\nಜ್ಞಾನದ ದಾರಿಯಲ್ಲಿ ಹೇಗೆ ಸಾಗಬೇಕು ಅನ್ನುವ ಅದ್ಭುತ ವಿಚಾರವನ್ನು ವಿವರಿಸುತ್ತಾನೆ.\n\nಅಧ್ಯಾತ್ಮದಲ್ಲಿ ತಿಳಿದುಕೊಳ್ಳಬೇಕಾದ ಸಂಗತಿ 'ಬ್ರಹ್ಮ' ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಬ್ರಹ್ಮ ಎನ್ನುವ ಪದ “ಅವ ವೃದ್ದೋ'\nಎನ್ನುವ ಧಾತುವಿನಿಂದ ಬಂದಿದೆ. ಅವತಿ ಎಂದರೆ ಎಲ್ಲಕ್ಕಿಂತ ದೊಡ್ಡದು-ಅದು ಓಂ. ಅಂದರೆ ಅನಾಧಿನಿತ್ಯ, ಸರ್ವ\nಗುಣಪೂರ್ಣ, ಸರ್ವಗತ, ಸರ್ವಸಮರ್ಥ ಭಗವಂತ ಬ್ರಹ್ಮ- ಅವನೇ ಓಂ. ಮುಖ್ಯವಾಗಿ ಈ ಶ್ಲೋಕದಲ್ಲಿ “ತೇ\nಬ್ರಹ್ಮ ತದ್‌ ವಿದುಃ” ಅಂದರೆ “ಎಲ್ಲಾ ಕಡೆ ಇರುವ ಭಗವಂತನನ್ನು ತಿಳಿಯುತ್ತಾರೆ' ಎಂದರ್ಥ. ಭಗವಂತನ\nಸರ್ವಗತತ್ವದ ಸಾಕ್ಷಾತ್ಕಾರವೇ ಬ್ರಹ್ಮಸಾಕ್ಷಾತ್ಕಾರ. ಬಿಂಬಸಾಕ್ಷಾತ್ಕಾರ ಅಂದರೆ ನಮ್ಮೊಳಗಿರತಕ್ಕಂತಹ\nಅಣೋರಣೀಯವಾಗಿರುವ ಭಗವಂತನ ಸಾಕ್ಷಾತ್ಕಾರ. ಇಂತಹ ಬಿಂಬರೂಪಿ ಭಗವಂತನೇ ಇಡೀ ವಿಶ್ವದಲ್ಲಿ\nವ್ಯಾಪ್ತನಾಗಿ ತುಂಬಿದ್ದಾನೆ ಎನ್ನುವುದು ಬ್ರಹ್ಮಸಾಕ್ಷಾತ್ಕಾರ. ಭಗವಂತನ ವ್ಯಾಪ್ತ ರೂಪವನ್ನು ನಾವು ಕಾಣಲು\nಸಾಧ್ಯವಿಲ್ಲ. ಆದರೆ ಆ ವ್ಯಾಪ್ತಿಯ ಅರಿವು ಬಹಳ ಮುಖ್ಯ. ಸೌರಶಕ್ತಿಯಲ್ಲಿ ತುಂಬಿ ಇಡೀ ಪ್ರಪಂಚವನ್ನು\nಬೆಳಗಿಸುವವನೂ ಅವನೇ, ನನ್ನೊಳಗಿದ್ದು ಬೆಳಗಿಸುವವನೂ ಅವನೇ ಎನ್ನುವ ಅರಿವು ಆತ್ಮ ಸಾಕ್ಷಾತ್ಕಾರ.\nಬಲಿಚಕ್ರವರ್ತಿಗೆ ಆದ ಅನುಭವ ಕೂಡಾ ಇದೇ. ನಿಮಗೆ ತಿಳಿದಿರುವಂತೆ ವಾಮನ ರೂಪಿ ಭಗವಂತ, ಮಹಾ\nದಾನಿ. ಬಲಿಚಕ್ರವರ್ತಿಯಲ್ಲಿ ಮೂರು ಹೆಜ್ಜೆ ಭೂಮಿಯನ್ನು ದಾನವಾಗಿ ಕೇಳುತ್ತಾನೆ. ಶುಕ್ರಾಚಾರ್ಯರ\nವಿರೋಧವನ್ನು ಲೆಕ್ಕಿಸದೆ ಬಲಿ ವಾಮನನಿಗೆ ದಾನ ಮಾಡಲು ಮುಂದಾಗುತ್ತಾನೆ. ಆಗ ವಾಮನನು ತನ್ನ\nಮೊದಲ ಹೆಜ್ಜೆಯಿಂದ ಭೂಮಿಯನ್ನೂ ಮತ್ತು ಎರಡನೇ ಹೆಜ್ಜೆಯಿಂದ ಆಕಾಶವನ್ನೂ ಆವರಿಸಿದಾಗ , ಮೂರನೇ\nಹೆಜ್ಜೆಗೆ ಬಲಿ ತನ್ನ ತಲೆಯನ್ನು ಅರ್ಪಿಸಿ ಪಾತಳವನ್ನು ಸೇರಿ ಉದ್ಧಾರವಾಗುತ್ತಾನೆ. ಈ ಕಥೆಯನ್ನು ನಾವು ಸ್ವಲ್ಪ\nಆಳವಾಗಿ ವಿಶ್ಲೇಷಿಸಿದರೆ ಕಥೆಯಲ್ಲಿ ಅಡಗಿರುವ ಸಾರ ತಿಳಿಯುತ್ತದೆ. ಸಂಸಾರ ಸಾಗರದಲ್ಲಿ ಮುಳುಗಿರುವ\nನಾವೆಲ್ಲರೂ ಒಂದು ರೀತಿಯಲ್ಲಿ ಬಲಿಗಳು. ಭಗವಂತನ ಸಾಕ್ಷಾತ್ಕಾರವಾಗಲು ನಾವೆಲ್ಲರೂ ಮಾನಸಿಕವಾಗಿ,\nಆಧ್ಯಾತ್ಮಿ| ಕವಾಗಿ ಬಲಿಷ್ಟ ರಾಗಬೇಕು. ಉಪಾಸನೆಯಲ್ಲಿ ಪ್ರಮುಖವಾಗಿ ಮೂರೂ ಹೆಜ್ಜೆಗಳಿವೆ. ಮೊದಲನೆಯದು\n\nಭಗವಂತನ ಪುಟ್ಟ (ವಾಮನ) ಮೂರ್ತಿಯನ್ನು ದೇವರು ಎಂದು ಆರಾಧಿಸುವುದು. ಎರಡನೇಯದು ಉಪಾಸನೆ\nಮಾಡುತ್ತಾ ಮಾಡುತ್ತಾ , ಭಗವಂತ ಕೇವಲ ಮೂರ್ತಿಯಲ್ಲಿ ಅಲ್ಲದೆ, ಇಡೀ ಲೋಕದಲ್ಲಿ ವ್ಯಾಪಿಸಿರುವ ಶಕ್ತಿ ಎಂದು\nತಿಳಿಯುವುದು. ಪ್ರಮುಖವಾದ ಮೂರನೇ ಹೆಜ್ಜೆ- ಭಗವಂತ ಸರ್ವಾಂತರ್ಯಾಮಿ, ಆತ ನನ್ನೊಳಗೂ\nತುಂಬಿದ್ದಾನೆ ಎಂದು ತಿಳಿದು, ಆ ಪರಶಕ್ತಿಗೆ ತಲೆಬಾಗುವುದು. ಆಗ ನಮಗೆ ನಿಜವಾದ ಭಗವಂತನ\nಸಾಕ್ಷಾತ್ಕಾರವಾಗುತ್ತದೆ, ಹಾಗೂ ಭಗವಂತ ನಮ್ಮನ್ನು ಉದ್ಧರಿಸುತ್ತಾನೆ. ಬಲಿ-ಭಗವಂತ.. ನನ್ನೊಳಗೆ\nಅಂತರ್ಯಾಮಿ(ಆತ್ಮನಿ. ವೇದನಂ) ಎಂದು ತಿಳಿದು. ಭಗವಂತನಿಗೆ ತನ್ನನ್ನು ಅರ್ಪಿಸಿಕೊಂಡ(ಆತ್ಮ\nನಿವೇದನಂ)ಅಥವಾ ತನ್ನ ತಲೆಯನ್ನು ಕೊಟ್ಟ. ಇದು ಮೂರು ಹೆಜ್ಜೆಯ ಪರಿಕಲ್ಪನೆ.\n\nಭಗವಂತ ಸರ್ವಗತ-ಸರ್ವಸಮರ್ಥ, ಅವನು ಎಲ್ಲವುದರ ಒಳಗೂ ಇದ್ದು ಎಲ್ಲವನ್ನೂ ಮಾಡುತ್ತಿದ್ದಾನೆ. ಅವನ\nಅಧೀನವಾಗಿರತಕ್ಕ ಪ್ರತಿಬಿಂಬ ಈ ಜೀವ ಎನ್ನುವ ಸತ್ಯ ತಿಳಿದಾಗ ಎಲ್ಲಾ ಕರ್ಮದ ರಹಸ್ಯ ತಿಳಿಯುತ್ತದೆ.\nಆದ್ದರಿಂದ ಅಧ್ಯಾತ್ಮದಲ್ಲಿ ತಿಳಿಯಬೇಕಾದ ಮೊದಲ ಮೂರು ವಿಚಾರ ಎಂದರೆ ಭಗವಂತನ ಪ್ರತಿಬಿಂಬವಾದ\nಜೀವ, ಪರಿಪೂರ್ಣ ಮತ್ತು ಸರ್ವಸಮರ್ಥನಾದ ಬ್ರಹ್ಮ, ಆ ಅನಂತ ಸಾಮರ್ಥ್ಯದಿಂದ ನಡೆಯುವ ಕರ್ಮ. ಇದೇ\nಬ್ರಹ್ಮ-ಕರ್ಮ-ಅಧಿಆತ್ಮ. ಈ ಮೂರು ವಿಚಾರವಲ್ಲದೆ ಇನ್ನೂ ಮೂರು ವಿಷಯಗಳನ್ನು ಕೃಷ್ಣ ಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ\nವಿವರಿಸುತ್ತಾನೆ.",
  "7.30": "ಸ ಅಧಿ ಭೂತ ಅಧಿದೈವಮ್‌ ಮಾಮ್‌ ಸ ಅಧಿಯಜ್ಞಮ್‌ ಚ ಯೇ ವಿದುಃ |\n\nಪ್ರಯಾಣ ಕಾಲೇ ಅಪಿ ಚ ಮಾಮ್‌ ತೇ ವಿದುಃ ಯುಕ್ತ ಚೇತಸಃ -ಯಾರು 'ಅಧಿಭೂತ' -“ಅಧಿದೈವ'ದ ಜತೆಗೆ\nನನ್ನನ್ನು ತಿಳಿಯುತ್ತಾರೋ ; ತಿಳಿದು ಕೊನೆಯ ಕ್ಷಣದಲ್ಲೂ ನನ್ನನ್ನು ನೆನೆಯುತ್ತಾರೋ, ನನ್ನಲ್ಲೇ ಬಗೆಯಿಟ್ಟ\nಅಂತವರು ನನ್ನನ್ನು ಬಲ್ಲವರು.\n\nಭಗವಂತನ ಅರಿವು ಮೂಡಬೇಕಾದರೆ ಮೊದಲು ಭೌತವಿಜ್ಞಾನ(ಅಧಿಭೂತ)ದ ಅರಿವಿರಬೇಕು. ಪಂಚ\nಭೂತಗಳು, ಈ ದೇಹ, ಬ್ರಹ್ಮಾಂಡ, ಪಿಂಡಾಂಡ, ಇಲ್ಲಿರುವ ದ್ರವ್ಯಗಳ ಅರಿವು ಸಾಧನೆಯ ಮೊದಲ ಹೆಜ್ಜೆ.\nಅಧಿಭೂತದ ನಂತರ ಅಧಿದೈವದ ಅರಿವು. ನಮ್ಮ ಪಂಚಭೂತಾತ್ಮಕವಾದ ಶರೀರದಲ್ಲಿ “ನೋಡುವುದು,\nಕೇಳುವುದು, ಅನುಭವಿಸುವುದು' ಇತ್ಯಾದಿ ಕ್ರಿಯೆ ನಿಯಮಬದ್ಧವಾಗಿ ಹೇಗೆ ನಡೆಯುತ್ತದೆ? ಜಡದಲ್ಲಿ ಕ್ರಿಯೆ ಇಲ್ಲ,\nಬದಲಿಗೆ ಅದರ ಹಿಂದಿರುವ ಅಭಿಮಾನಿ ದೇವತೆಗಳು ಒಂದೊಂದು ಇಂದ್ರಿಯದಲ್ಲಿದ್ದು ಒಂದೊಂದು ಕ್ರಿಯೆಯನ್ನು\nನಿಯಂತ್ರಿಸುತ್ತಿದ್ದಾರೆ-ಇದು ಅಧಿದೈವದ ತಿಳುವಳಿಕೆ. ಇಂತಹ ಸಹಸ್ರಾರು ದೇವತೆಗಳನ್ನು ನಿಯಂತ್ರಿಸುವ\nಅಧ್ಯಕ್ಷ ಆ ಭಗವಂತ. ಈ ಪ್ರಪಂಚದಲ್ಲಿ ಅಥವಾ ಪಿಂಡಾಂಡದಲ್ಲಿ ನಡೆಯುವ ಪ್ರತಿಯೊಂದು ಕ್ರಿಯೆ ಒಂದು ಯಜ್ಞ.\nಆ ಯಜ್ಞವನ್ನು ಅಧ್ಯಕ್ಷನಾಗಿ ನಡೆಸುವವನು ಅಧಿಯಜ್ಞ. ಆತ ಸಮಸ್ತ ದೇವತೆಗಳ ನಿಯಾಮಕನಾದ ಭಗವಂತ.\n\nಒಟ್ಟಿನಲ್ಲಿ ನಾವು ಆರು ವಿಚಾರವನ್ನು ಸ್ಪಷ್ಟವಾಗಿ ತಿಳಿದುಕೊಳ್ಳಬೇಕು. ೧. ಅಧಿಭೂತ-ಭೌತಿಕ ಪ್ರಪಂಚ,; ೨.\nಅಧ್ಯಾತ್ಮ-ಜೀವಾತ್ಮ ; ೩. ಅಧಿದೈವ-ಸಮಸ್ತ ತತ್ವಾಭಿಮಾನಿ ದೇವತೆಗಳು ; ೪. ಅಧಿಯಜ್ಞ-ಸರ್ವ ನಿಯಾಮಕ\nಭಗವಂತ; ೫. ಬ್ರಹ್ಮ ಸಾಕ್ಷಾತ್ಕಾರ -ಅಂತರ್ಯಾಮಿಯಾಗಿರುವ ಬಿಂಬ ರೂಪಿ ಭಗವಂತನೇ ಎಲ್ಲಾ ಕಡೆ\nತುಂಬಿದ್ದಾನೆ ಎನ್ನುವ ಅರಿವು; ೬. ಎಲ್ಲಾ ಕರ್ಮಗಳೂ ಆ ಭಗವಂತನ ಅಧೀನವಾಗಿ ನಡೆಯುತ್ತವೆ ಎನ್ನುವ ಸತ್ಯ.\nಈ ಆರು ವಿಚಾರಗಳೂ ನಮ್ಮ ಜೀವನದ ಕೊನೆಯ ಕ್ಷಣದಲ್ಲಿ(ದೇಹ ತ್ಯಾಗ ಮಾಡುವಾಗ)ಕೂಡಾ ನಮ್ಮ\nಮನದಲ್ಲಿ ಗಾಢವಾಗಿ ನಿಂತಿರಬೇಕು. ನಾವು ದೇಹ ತ್ಯಾಗ ಮಾಡುವಾಗ ನಮ್ಮ ಮನದಲ್ಲಿ ಯಾವುದು\nಗಾಢವಾಗಿ ನಿಂತಿರುತ್ತದೋ ಅದು ನಮ್ಮ ಮುಂದಿನ ಜನ್ಮವನ್ನು ನಿರ್ಧರಿಸುತ್ತದೆ. ಇದಕ್ಕಾಗಿ ಜೀವಮಾನದಲ್ಲಿ\nಭಗವಂತನ ಅರಿವು. ಬಹಳ ಮುಖ್ಯ. “ಸಾಧನೆಯಲ್ಲಿ ಎಂದೂ ಯಾವುದೇ ಮೋಹಕ್ಕೊಳಗಾಗದೆ,\nಅಂತ್ಯಕಾಲದಲ್ಲೂ ಸದಾ ಭಗವಂತನನ್ನು ಚಿಂತಿಸುವವನು ನನ್ನನ್ನು ಸೇರುತ್ತಾನೆ” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.\n\nಹೀಗೆ ಈ ಅಧ್ಯಾಯದಲ್ಲಿ ಜ್ಞಾನದ ವೈಭವವನ್ನು ನಮ್ಮ ಮುಂದೆ ತೆರೆದಿಟ್ಟ ಕೃಷ್ಣ, ಮುಂದಿನ ಅಧ್ಯಾಯದಲ್ಲಿ\nಅಧಿಭೂತ, ಅಧಿದೈವ, ಅಧ್ಯಾತ್ಮ, ಅಧಿಯಜ್ಞ, ಬ್ರಹ್ಮ, ಕರ್ಮ ಇದರ ವಿಸ್ತಾರವಾದ ವಿವರಣೆಯನ್ನು\nವಿವರಿಸುತ್ತಾನೆ.\n\nಇತಿ ಸಪ್ತಮೋ$ಧ್ಯಾಯಃ\nಏಳನೆಯ ಅಧ್ಯಾಯ ಮುಗಿಯಿತು\n\nಅಧ್ಯಾಯ ಎಂಟು\n\nಏಳನೆಯ ಅಧ್ಯಾಯದ ಕೊನೆಯಲ್ಲಿ ಕೃಷ್ಣ ಸಂಕ್ಷಿಪ್ತವಾಗಿ ಆರು ಮಹತ್ವದ ಸಂಗತಿಯನ್ನು ಮನುಷ್ಯ ತಿಳಿದಿರಬೇಕು\nಎಂದು ಹೇಳಿದ್ದ. ಅಧಿಭೂತ, ಅಧ್ಯಾತ್ಮ, ಅಧಿದೈವ, ಅಧಿಯಜ್ಞ, ಬ್ರಹ್ಮ, ಕರ್ಮ-ಈ ಆರು ಸಂಗತಿಗಳನ್ನು ತಿಳಿದರೆ\nಅದರಿಂದ ಮೇಲಕ್ಕೆ ಏರುವ ಇನ್ನೊಂದು ಮೆಟ್ಟಲಿರುವುದಿಲ್ಲ ಎಂದಿದ್ದ ಕೃಷ್ಣ.\n\nಅಧಿಭೂತ ಎಂದರೆ ಭೌತಿಕ ಪ್ರಪಂಚ, ಅಧ್ಯಾತ್ಮ ಎಂದರೆ ಜಡದೊಳಗಿರುವ ಚೇತನ, ಅಧಿದೈವ ಎಂದರೆ\nಚೇತನವನ್ನು ನಿಯಂತ್ರಿಸುವ ದೇವತೆಗಳು, ಅಧಿಯಜ್ಞ ಎಂದರೆ ದೇವತೆಗಳನ್ನು ನಿಯಂತ್ರಿಸುವ ಭಗವಂತ, ಈ\nಅಧಿಯಜ್ಞ ಜಗತ್ತಿನಲ್ಲೆಲ್ಲಾ ತುಂಬಿದ್ದಾನೆ ಎನ್ನುವುದು ಬ್ರಹ್ಮಕಲ್ಪನೆ, ಅವನಿಂದಲೇ ಎಲ್ಲಾ ಕ್ರಿಯೆಗಳೂ\nನಡೆಯುತ್ತವೆ-ಆತನೇ ಸೂತ್ರದಾರ. ಈ ಅರಿವು ಸಾವಿನ ಸಮಯದಲ್ಲೂ ಎಚ್ಚರವಾಗಿರಬೇಕು ಆಗ ಆ ಸಾವು\nಮಾಂಗಲಿಕ. ಇಷ್ಟು ವಿಚಾರವನ್ನು ನಾವು ಹಿಂದಿನ ಅಧ್ಯಾಯದಲ್ಲಿ ನೋಡಿದ್ದೇವೆ.\n\nಸೂಕ್ಷ್ಮವಾಗಿ ಏಳನೇ ಅಧ್ಯಾಯದ ಕೊನೆಯ ಎರಡು ಶ್ಲೋಕಗಳನ್ನು ಗಮನಿಸಿದರೆ ಅಲ್ಲಿ ಕೃಷ್ಣ 'ತತ್‌ ಬ್ರಹ್ಮ'(ಆ\nಬ್ರಹ್ಮತತ್ವ) ಎಂದಿದ್ದಾನೆ. ಕೊನೆಯಲ್ಲಿ “ನನ್ನನ್ನು(ಮಾಂ) ಸೇರುತ್ತಾರೆ' ಎಂದಿದ್ದಾನೆ. ಇಲ್ಲಿ ನಮಗೆ ಕೃಷ್ಣ ಮತ್ತು\nಬ್ರಹ್ಮತತ್ವ ಬೇರೆ ಬೇರೆಯೋ ಅನ್ನುವ ಸಂಶಯ ಬರುತ್ತದೆ. ಇನ್ನು ಇಲ್ಲಿ ಕೃಷ್ಣ ಬಳಸಿದ ಪದಗಳನ್ನು ನೋಡಿದಾಗ\nಅಲ್ಲಿ ಅನೇಕ ಅರ್ಥವನ್ನು ಕಾಣುತ್ತೇವೆ. ಉದಾಹರಣೆಗೆ ಬ್ರಹ್ಮ ಎನ್ನು ವ ಪದಕ್ಕೆ ಸಂಸ್ಕೃತದಲ್ಲಿ ಅನೇಕ ಅರ್ಥವಿದೆ.\nಬ್ರಹ್ಮ ಎಂದರೆ ಜೀವ, ಚತುರ್ಮುಖ ಬ್ರಹ್ಮ, ಶ್ರೀತತ್ವ, ಭಗವಂತ, ವೇದಗಳು, ಇತ್ಯಾದಿ. ಅಧ್ಯಾತ್ಮ ಎನ್ನುವಲ್ಲಿ\n\"ಆತ್ಮ' ಪದಕ್ಕೆ ಶರೀರ, ಮನಸ್ಸು, ಜೀವ, ಪರಮಾತ್ಮ ಇತ್ಯಾದಿ ಅರ್ಥಗಳಿವೆ. 'ಕರ್ಮ' ಎನ್ನುವಲ್ಲಿ ಪ್ರಾರಾಬ್ಧಕರ್ಮ\nಮತ್ತು ಕರ್ತವ್ಯಕರ್ಮ ಎನ್ನುವ ಎರಡು ಅರ್ಥ ಕಾಣುತ್ತದೆ. ಅಧಿಭೂತ ಎನ್ನುವಲ್ಲಿ ಭೂತ' ಪದಕ್ಕೆ ಜಡ ಹಾಗೂ\nಚೇತನ ಎನ್ನುವ ಎರಡು ಅರ್ಥವನ್ನು ಕಾಣಬಹುದು. ಇದೇ ರೀತಿ ಅಧಿದೈವ ಎಂದರೆ ದೈವರಲ್ಲಿ(ದೇವತೆಗಳಲ್ಲಿ)\nಅಧಿಕನಾದವನು ಅಧಿದೈವ, ದೇವತೆಗಳಿಗೆ ಸಂಬಂಧಪಟ್ಟಿದ್ದೂ ಕೂಡಾ ಅಧಿದೈವ. ಹೀಗೆ ಈ ಆರೂ ಶಬ್ದಗಳು\nಬೇರೆ ಬೇರೆ ಸಂದರ್ಭದಲ್ಲಿ ಬೇರೆ ಬೇರೆ ಆಯಾಮದಲ್ಲಿ ತೆರೆದುಕೊಳ್ಳುವಂತಾದ್ದು. ಹೀಗಿರುವಾಗ ಕೃಷ್ಣ ಹೇಳಿರುವ\nಈ ಆರು ಸಂಗತಿಯನ್ನು ಸ್ಪಷ್ಟವಾಗಿ ಅರ್ಥ ಮಾಡಿಕೊಳ್ಳುವುದು ಕಷ್ಟ.\n\nಕೊನೆಯ ಶ್ಲೋಕದಲ್ಲಿ ಕೃಷ್ಣ ಹೇಳಿದ: “ನಮ್ಮ ಜೀವನ ಪಯಣದ ಕೊನೆಯ ಕ್ಷಣದಲ್ಲಿ ಈ ಅರಿವನ್ನು\nಉಳಿಸಿಕೊಂಡಿರಬೇಕು” ಎಂದು. ಅದು ಹೇಗೆ ಸಾಧ್ಯ ? ದೇಹತ್ಯಾಗ ಮಾಡುವಾಗ ಮಾನಸಿಕ ಚಿಂತನೆ\nಹೇಗಿರಬೇಕು? ದೇಹತ್ಯಾಗ ನಂತರ ಜೀವ ಯಾವ ಮಾರ್ಗದಲ್ಲಿ ಚಲಿಸುತ್ತದೆ? ಇತ್ಯಾದಿ ಪ್ರಶ್ನೆ ನಮ್ಮನ್ನು\nಕಾಡುತ್ತದೆ. ಎಂಟನೇ ಅಧ್ಯಾಯ ನಮ್ಮೆಲ್ಲರ ಪ್ರತಿನಿಧಿ ಅರ್ಜುನ ಈ ನಮ್ಮ ಪ್ರಶ್ನೆಯನ್ನು ಶ್ರೀಕೃಷ್ಣನಲ್ಲಿ\nಕೇಳುವುದರೊಂದಿಗೆ ಪ್ರಾರಂಭವಾಗುತ್ತದೆ.",
  "8.1": "ಅರ್ಜುನಃ ಉವಾಚ\n\nಕಿಮ್‌ ತತ್‌ ಬ್ರಹ್ಮ ಕಿಮ್‌ ಅಧ್ಯಾತ್ಮಮ್‌ ಕಿಮ್‌ ಕರ್ಮ ಪುರುಷೋತ್ತಮ ।\n\nಅಧಿಭೂತಮ್‌ ಚ ಕಿಮ್‌ ಪ್ರೋಕ್ತಮ್‌ ಅಧಿದೈವಮ್‌ ಕಿಮ್‌ ಉಚ್ಯತೇ -ಅರ್ಜುನ ಕೇಳಿದನು: ಪುರುಷೋತ್ತಮಾ,\nಯಾವುದು. ಆ. 'ಬ್ರಹ್ಮ'? 'ಅಧ್ಯಾತ್ಮ'ವೆಂದರೆ. ಏನು? ಏನು 'ಕರ್ಮ'ವೆಂದರೆ? ಯಾವುದನ್ನು\n\"ಅಧಿಭೂತ'ವೆನ್ನುತ್ತಾರೆ? ಯಾವುದನ್ನು 'ಅಧಿದೈವ'ವೆನ್ನುತ್ತಾರೆ?\n\nಅರ್ಜುನ ಕೃಷ್ಣನನ್ನು ಕೇಳುತ್ತಾನೆ “ ತತ್‌ ಬ್ರಹ್ಮ(ಆ ಬ್ರಹ್ಮತತ್ವ) ಅಂದರೆ ಯಾವುದು? ಅಧ್ಯಾತ್ಮ ಅಂದರೆ ಏನು?\nಮತ್ತು ಕರ್ಮ ಅಂದರೇನು?” ಎಂದು. ಇಲ್ಲಿ ವ್ಯಾಸರು ಅರ್ಜುನನ ಈ ಪ್ರಶ್ನೆಯ ಹಿಂದಿನ ಭಾವನೆಯನ್ನು\n“ಪುರುಷೋತ್ತಮ” ಎನ್ನುವ ವಿಶೇಷಣದಲ್ಲಿ ಸೆರೆಹಿಡಿದು ನಮ್ಮ ಮುಂದಿಟ್ಟಿದ್ದಾರೆ. ಪುರುಷೋತ್ತಮ ಎಂದರೆ\nಕ್ಷರ(ಜೀವ)ವನ್ನು ಮೀರಿನಿಂತವನು. ಅಕ್ಷರ(ಶ್ರೀತತ್ವ)ಕ್ಕಿಂತಲೂ ಹಿರಿಯನು. “ಕ್ಷರ-ಅಕ್ಷರವನ್ನು ಮೀರಿ ನಿಂತ\nನೀನೇ ಪುರುಷೋತ್ತಮ, ನೀನಲ್ಲದೆ ನಿನ್ನಿಂದ ಹಿರಿದಾದ ತತ್ವ ಇನ್ನೊಂದಿಲ್ಲ, ಆದ್ದರಿಂದ ನನಗೆ ತಿಳಿದಂತೆ ನೀನೇ\nಬ್ರಹ್ಮ. ಇದರ ವಿವರಣೆಯನ್ನು ನಿನ್ನಿಂದ ತಿಳಿಯಬೇಕು” ಎನ್ನುವ ಭಾವವನ್ನು ಅರ್ಜುನ ವ್ಯಕ್ತಪಡಿಸಿದ\nಎನ್ನುವುದನ್ನು ತಿಳಿಸುವ ವಿಶೇಷಣ 'ಪುರುಷೋತ್ತಮ'. ಅರ್ಜುನ ಕೇಳುತ್ತಾನೆ. “ಯಾವುದನ್ನು\nಅಧಿಭೂತವೆನ್ನುತ್ತಾರೆ? ಯಾವುದನ್ನು ಅಧಿದೈವವೆನ್ನುತ್ತಾರೆ?” ಎಂದು.\n",
  "8.2": "ಅಧಿಯಜ್ಞಃ ಕಥಮ್‌ ಕಃ ಅತ್ರ ದೇಹೇ ಅಸ್ಮಿನ್‌ ಮಧುಸೂದನ ।\nಪ್ರಯಾಣ ಕಾಲೇ ಚ ಕಥಮ್‌ ಜ್ಟೇಯಃ ಅಸಿ ನಿಯತ ಆತ್ಮಭಿಃ -ಮಧುಸೂದನಾ, ಇಲ್ಲಿ ಈ ದೇಹದಲ್ಲಿ\n\"ಅಧಿಯಜ್ಞ'ಯಾರು? ಮತ್ತು ಹೇಗೆ? ಬಗೆ ಹಿಡಿತದಲ್ಲಿಟ್ಟವರು ಕೊನೆಯ ಕಾಲದಲ್ಲಿ ನಿನ್ನ ನ್ನು ಹೇಗೆ ನೆನೆಯಬೇಕು?\n\nಮುಂದುವರಿದು ಅರ್ಜುನ ಕೇಳುತ್ತಾನೆ: “ಅಧಿಯಜ್ಞ ಅಂದರೆ ಯಾರು?” ಎಂದು. ನಮ್ಮ ದೇಹದೊಳಗಿರುವ\nಅಧಿಯಜ್ಞ ಯಾರು ಮತ್ತು ಹೇಗೆ? ಅಧಿಯಜ್ಞದ ಅರ್ಥವ್ಯಾಪ್ತಿ ಏನು? ಎನ್ನುವುದು ಅರ್ಜುನನ ಪ್ರಶ್ನೆ. ಇಲ್ಲಿ ಪುನಃ\nವ್ಯಾಸರು “ಮಧುಸೂದನ” ಎನ್ನುವ ವಿಶೇಷಣವನ್ನು ಬಳಸಿ ಅರ್ಜುನನ ಪ್ರಶ್ನೆಯ ಭಾವನೆಯನ್ನು ನಮಗೆ\nತಿಳಿಸುತ್ತಾರೆ. “ಮಧುಸೂದನ” ಅನ್ನುವ ನಾಮಕ್ಕೆ ಎರಡು ಪ್ರಮುಖ ಅರ್ಥವಿದೆ. \"ಮಧು' ಅಂದರೆ\nಆನಂದ(Inner bliss). \"ಸೂದ' ಎಂದರೆ ಸತ್ಕರ್ಮವನ್ನು ಮಾಡುವ ಸಾತ್ವಿಕರು. ಆದ್ದರಿಂದ ಮಧುಸೂದನ\n\nಎಂದರೆ ಸಾತ್ವಿಕರೊಳಗಿದ್ದು ಅವರಿಗೆ ಆನಂದವನ್ನು ಕೊಡುವವನು ಎಂದರ್ಥ. “ಸೂದ' ಎಂದರೆ ನಾಶ ಎನ್ನುವ\nಇನ್ನೊಂದು ಅರ್ಥವಿದೆ. ಆದ್ದರಿಂದ ದುರ್ಜನರ ಆನಂದವನ್ನು ನಾಶಮಾಡುವವನು ಮಧುಸೂದನ. “ನಮ್ಮೊಳಗೆ\nಕೂತು ಆನಂದ ಕೊಡುವವನೂ ನೀನೇ, ದುಃಖ ಕೊಡುವವನೂ ನೀನೇ. ನಮ್ಮೊಳಗಿದ್ದು ಎಲ್ಲಾ ಯಜ್ಞಗಳನ್ನು\nನಿಯಂತ್ರಿಸುವವನು ನೀನೆ. ಆದ್ದರಿಂದ ನೀನೇ ಅಧಿಯಜ್ಞ ಎನ್ನುವುದು ನನ್ನ ತಿಳುವಳಿಕೆ. ಇದನ್ನು ನನಗೆ\nವಿವರಿಸು” ಎನ್ನುವ ಅರ್ಜುನನ ಭಾವವನ್ನು ಈ ವಿಶೇಷಣದ ಮೂಲಕ ವ್ಯಾಸರು ಇಲ್ಲಿ ವಿವರಿಸಿದ್ದಾರೆ. ಅರ್ಜುನ\nಕೇಳುತ್ತಾನೆ “ನಮ್ಮ ಜೀವನದ ಕೊನೆಯ ಶ್ರೇಷ್ಠವಾದ ಯಾತ್ರೆಯಲ್ಲಿ ಜೀವದ ದೇಹ ನಿರ್ಗಮನದ ಅನುಸಂಧಾನ\nಮತ್ತು ಹೋಗುವ ವಿವರವನ್ನು ತಿಳಿಸು” ಎಂದು.\n\nಮೇಲಿನ ಶ್ಲೋಕದಲ್ಲಿ ಉಪಯೋಗಿಸಿದ ಪುರುಷೋತ್ತಮ ಮತ್ತು ಮಧುಸೂದನ ಎನ್ನುವ ಎರಡು ವಿಶೇಷಣದ\nಹಿಂದಿನ ಅರ್ಥವನ್ನು ನೋಡಿದಾಗ ನಮಗೆ ಸ್ಪಷ್ಟವಾಗಿ ತಿಳಿಯುತ್ತದೆ-ಅರ್ಜುನನಿಗೆ ಈ ಆರು ಸಂಗತಿಯ\n(ಪದಗಳ) ನಿಜವಾದ ಅರ್ಥ ತಿಳಿದಿತ್ತು ಎಂದು. ಆದರೂ ಅದರ ವಿವರವನ್ನು ಭಗವಂತನಿಂದ ತಿಳಿದುಕೊಳ್ಳುವ\nಉದ್ದೇಶದಿಂದ ಆತ ಈ ಪ್ರಶ್ನೆಯನ್ನು ಕೃಷ್ಣನಲ್ಲಿ ಕೇಳುತ್ತಾನೆ. ಸಾಮಾನ್ಯವಾಗಿ ತಿಳಿದವರು ತಮಗೆ ತಿಳಿದಿದ್ದರೂ\nಕೂಡಾ ಇನ್ನೊಬ್ಬರಿಗೆ ತಿಳಿಸುವ ಉದ್ದೇಶದಿಂದ ಈ ರೀತಿ ಪ್ರಶ್ನೆ ಮಾಡುತ್ತಾರೆ. ಇಲ್ಲಿ ಅರ್ಜುನ ತಾನು\nತಿಳಿದಿರುವುದನ್ನು ದೃಡೀಕರಿಸಿಕೊಳ್ಳುವುದಕ್ಕೋಸ್ಕರ ಮತ್ತು ಇಡೀ ಮಾನವ ಜನಾಂಗಕ್ಕೆ ಭಗವಂತನ\nವಿವರಣೆಯನ್ನು ತಿಳಿಸುವುದಕ್ಕೋಸ್ಕರ ಈ ಪ್ರಶ್ನೆಯನ್ನು ಕೃಷ್ಣನ ಮುಂದಿಟ್ಟಿದ್ದಾನೆ.\n\nನಮಗೆ ಅನಿಸಬಹುದು “ಯುದ್ಧರಂಗದಲ್ಲಿ ನಿಂತಿರುವ ಅರ್ಜುನ ಏಕೆ ಇಂತಹ ಪ್ರಶ್ನೆಗಳನ್ನು ಕೇಳುತ್ತಿದ್ದಾನೆ? ಇಲ್ಲಿ\nಅದರ ಅಗತ್ಯ ಏನಿದೆ?” ಎಂದು. ಸಾಮಾನ್ಯವಾಗಿ ಯುದ್ಧರಂಗದಲ್ಲಿ ನಿಂತವರಿಗೆ ಸಾವು ಕಾಡುವಷ್ಟು\nಇನ್ಯಾರನ್ನೂ ಕಾಡುವುದಿಲ್ಲ. ಅವರನ್ನು ಪ್ರತೀಕ್ಷಣ ಸಾವು ನಿರೀಕ್ಷಿಸುತ್ತಿರುತ್ತದೆ. ಅವರು ಸಾವು ಮತ್ತು ಸಾವಿನ\nಆಚೆಗಿನ ಸ್ಥಿತಿಯ ಬಗ್ಗೆ ಜಾಗೃತರಾಗಿರುತ್ತಾರೆ. ಸಾವಿನಿಂದಾಚೆಗೆ ಏನು ಎನ್ನುವುದು ಸೈನಿಕರಿಗೆ ಬಹಳ\nಮಹತ್ವದ್ದಾಗಿರುತ್ತದೆ. ಈವರೆಗಿನ ಕೃಷ್ಣಾರ್ಜುನ ಸಂವಾದದಲ್ಲಿ ಎಲ್ಲಿಯೂ ಕೃಷ್ಣ ಅರ್ಜುನನಿಗೆ ಗೆಲುವಿನ\nಭರವಸೆಯನ್ನು ಕೊಟ್ಟಿಲ್ಲ. ಧರ್ಮದ ಪರ ಹೋರಾಡುವುದು ನಿನ್ನ ಕರ್ತವ್ಯ ಅಂದಿದ್ದಾನೆ ಅಷ್ಟೇ. ಆದ್ದರಿಂದ\nಯುದ್ಧರಂಗದಲ್ಲಿರುವ ಅರ್ಜುನನಿಗೆ ಸಾವು ಮತ್ತು ಸಾವಿನಿಂದಾಚೆಗೆ ಏನು ಎನ್ನುವುದು ಬಹಳ ಮುಖ್ಯ ವಿಚಾರ.\nಅರ್ಜುನನ ಪ್ರಶ್ನೆ ಗೆ ಭಗವಂತನ ಉತ್ತರವೇ ಎಂಟನೆಯ ಅಧ್ಯಾಯದ ಉಳಿದ ಭಾಗ.",
  "8.3": "ಭಗವಾನ್‌ ಉವಾಚ - ಭಗವಂತ ಹೇಳಿದನು:\n\nಅಕ್ಷರಮ್‌ ಬ್ರಹ್ಮ ಪರಮಮ್‌ ಸ್ವಭಾವಃ ಅಧ್ಯಾತ್ಮಮ್‌ ಉಚ್ಯತೇ ।\n\nಭೂತ ಭಾವ ಉದ್ಭವ ಕರಃ ವಿಸರ್ಗಃ ಕರ್ಮ ಸಂಜ್ಞೆತಃ -- ಪರಮಾಕ್ಷರ ಎನಿಸಿದ ಪರತತ್ವವೇ “ಬ್ರಹ್ಮ”.\nಜೀವಸ್ವರೂಪ ಮತ್ತು ಜೀವಕ್ಕೆ ಸಂಬಂಧಿಸಿದ ಸಮಷ್ಟಿ ಪಿಂಡಾಂಡವನ್ನು [ಭಗವಂತನ ಬಗೆಯ ನಿಲುವನ್ನು]\n\n\"ಅಧ್ಯಾತ್ಮ' ಎನ್ನುತ್ತಾರೆ. ಜೀವ-ಜಡಗಳ ಅಭಿವ್ಯಕ್ತಿಗೆ ಕಾರಣವಾದ ಭಗವಂತನ ಬಗೆಬಗೆಯ ಸೃಷ್ಟಿಕ್ರಿಯೆಗೆ\n'ಕರ್ಮ' ಎಂದು ಹೆಸರು.\n\nಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ಬ್ರಹ್ಮ' ಅಂದರೆ “ಪರಮಂ ಬ್ರಹ್ಮ -ಪರಮಂ ಅಕ್ಷರ' ಎಂದು. ಭಗವಂತ ಎಲ್ಲರಿಗಿಂತ\nಹಿರಿದಾದ ಪರಮಮ್‌ ಬ್ರಹ್ಮ- ಆತ ಪರಮಾಕ್ಷರ. ಅಂತಹ ಭಗವಂತನ ಬಗೆಗೆ ತಿಳಿದುಕೊಳ್ಳಬೇಕು ಎನ್ನುವುದು\n\"ಬ್ರಹ್ಮ' ಪದದ ಹಿಂದಿನ ಅರ್ಥ. ವಿಷ್ಣು ಸಹಸ್ರನಾಮದಲ್ಲಿ ಭಗವಂತನನ್ನು ಈ ರೀತಿ ವರ್ಣಿಸಿದ್ದಾರೆ:\n\nಪರಮಂ ಯೋ ಮಹತ್ತೇಜಃ ಪರಮಂ ಯೋ ಮಹತ್ತಪಃ |\n\nಪರಮಂಯೋ ಮಹದ್ಭ ಹ್ಮ ಪರಮಂ ಯಃ ಪರಾಯಣಮ್‌ ॥\nಭಗವಂತ ಬೆಳಕುಗಳಿಗೆ ಬೆಳಕು ನೀಡುವ ಸ್ವರೂಪ; ಎಲ್ಲರ ಚಿಂತನೆಯ ಕೊನೆಯ ಗುರಿ; ಎಲ್ಲಾ ಜ್ಞಾನದ ಗಮ್ಯ ಆ\nಭಗವಂತ. ಇಲ್ಲಿ ಭಗವಂತನನ್ನು 'ಪರಮ ಮಹಾ ಬ್ರಹ್ಮ' ಎನ್ನುತ್ತಾರೆ. ಬ್ರಹ್ಮ ಎಂದರೆ ಜೀವರು; ಪರಬ್ರಹ್ಮ\nಎಂದರೆ ಮುಕ್ತರಾದ ಜೀವರು; ಪರಮಬ್ರಹ್ಮ ಎಂದರೆ ಶ್ರೀತತ್ವ,-ನಿತ್ಯ ಮುಕ್ತಳಾದ ಶ್ರೀಲಕ್ಷ್ಮಿ. ಪರಮ ಮಹಾ\nಬ್ರಹ್ಮ ಎಂದರೆ ನಾರಾಯಣ. ಭಗವಂತ ಪರಾಯಣರಿಗೂ ಕೂಡಾ ಪರಮ. ಇಲ್ಲಿ ಪರಾಯಣರು ಎಂದರೆ ನಮಗೆ\nಆಸರೆಯಾಗಿರುವ ತತ್ತ್ವಾಭಿಮಾನಿ ದೇವತೆಗಳು. ಭಗವಂತ ಸರ್ವ ದೇವತೆಗಳ ಒಡೆಯ. ಇದು ನಾವು\nತಿಳಿದುಕೊಳ್ಳಬೇಕಾದ ಆರು ಸಂಗತಿಗಳಲ್ಲಿ ಒಂದಾದ “ಬ್ರಹ್ಮ' ಪದದ ಅರ್ಥ.\nಮುಂದುವರಿದು ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಸ್ವಭಾವಃ ಅಧ್ಯಾತ್ಮಮ್‌ ಉಚ್ಯತೇ” ಎಂದು. ಇಲ್ಲಿ ಸ್ವಭಾವ ಎಂದರೆ\nತನ್ನತನ. ಜೀವದ ಇರವಿನ ಬಗೆ ಮತ್ತು ಜೀವ ಸ್ವಭಾವ. ನಾವು ಭಗವಂತನನ್ನು ಅರಿಯುವ ಮೊದಲು ನಮ್ಮ\nಜೀವ ಸ್ವಭಾವವನ್ನು ಅರಿಯಬೇಕು. ನಾನು ಅಂದರೆ ಏನು? ನನ್ನಲ್ಲಿರುವ ಉತ್ತಮ ಅಂಶ(plus point)\nಯಾವುದು? ಕೆಟ್ಟ ಅಂಶ(minus point) ಯಾವುದು ಎಂದು ನಿರಂತರ ನಾವು ನಮ್ಮನ್ನು ತಿಳಿಯಲು\nಪ್ರಯತ್ನಿಸಬೇಕು [ಆದರೆ ನಾವು ನಮ್ಮ ಹೆಚ್ಚಿನ ಸಮಯವನ್ನು ಇನ್ನೊಬ್ಬರ ಬಗ್ಗೆ ತೀರ್ಪು ಕೊಡುವುದರಲ್ಲಿ\nಕಳೆಯುತ್ತೇವೆ!॥] . ನಮಗೆ ಈ ದೇಹದಲ್ಲಿ ಕಣ್ಣು, ಕೈ, ಕಾಲು ಹಾಗೂ ಇತರ ಅಂಗಾಂಗಗಳನ್ನು ಬಿಟ್ಟು ಒಂದು\n\"ನಾನು' ಅನ್ನು ವ ವಸ್ತುವಿದೆ ಎನ್ನು ವ ಅರಿವೇ ಇರುವುದಿಲ್ಲ ಮೊದಲು ನಾವು ಜೀವದ\nಇರುವಿಕೆಯನ್ನು ತಿಳಿದುಕೊಳ್ಳಬೇಕು. ನಂತರ ಅದರ ಸ್ವಭಾವವೇನು ಎಂದು ತಿಳಿಯಬೇಕು. [ಸಾಮಾನ್ಯವಾಗಿ\nನಮಗೆ ನಮ್ಮ ಜೀವ ಸ್ವಭಾವ ಏನು ಎಂದು ತಿಳಿದಿರುವುದಿಲ್ಲ. ನಾವು ಪ್ರಭಾವದಲ್ಲೇ ಬದುಕುತ್ತಿರುತ್ತೇವೆ.]\nಜೀವ ಅನ್ನು ವುದು ಅತೀ ಸೂಕ್ಷ್ಮವಾದ ವಸ್ತು. ಅದು ಹೃತ್ಕಮಲ ಮಧ್ಯದಲ್ಲಿ ಅನಾಹತ ಚಕ್ರ(Anahata chakra)ವೆಂಬ ಶಕ್ತಿ ಕೇಂದ್ರದಲ್ಲಿದೆ. ಈ ಜೀವ ಎನ್ನುವುದು ಕೋಣೆಯಲ್ಲಿ ಹಚ್ಚಿದ ಪುಟ್ಟ ದೀಪದಂತೆ. ದೀಪ ಇಡೀ\nಕೋಣೆಯನ್ನು ಬೆಳಗಿಸುವಂತೆ, ಜೀವ ಅತಿ ಸೂಕ್ಷ್ಮವಾದರೂ ಕೂಡಾ ಅದರ ಬೆಳಕು ಇಡೀ ದೇಹವನ್ನು\nವ್ಯಾಪಿಸಿರುತ್ತದೆ. ಇಂತಹ ಜೀವ ಮತ್ತು ಜೀವ ಸ್ವಭಾವವೇ \"ಅಧ್ಯಾತ್ಮ'.\nಕೃಷ್ಣ ಮುಂದುವರಿದು ಹೇಳುತ್ತಾನೆ: “ಈ ಪ್ರಪಂಚ ಎಂದರೆ ಭೂತ ಮತ್ತು ಭಾವ-ಅಂದರೆ ಇದು ಜೀವ ಮತ್ತು\nಜಡದ ಸೃಷ್ಟಿ” ಎಂದು. ನಾವು ಈ ಜಗತ್ತಿನಲ್ಲಿದ್ದೇವೆ. ಇಂತಹ ಜಗತ್ತು ಹೇಗೆ ಸೃಷ್ಟಿಯಾಯಿತು? ಯಾವಾಗ\nಸೃಷ್ಟಿಯಾಯಿತು? ಅದರ ಹಿಂದಿರುವ ಮೂಲದ್ರವ್ಯ ಯಾವುದು? ಅದರ ನಿಮಿತ್ತ ಮತ್ತು ಉಪಧಾನ ಕಾರಣ\nಯಾರು? ಜೀವ ದೇಹದಮೂಲಕ ಹುಟ್ಟುವುದು ಏಕೆ? ಎಲ್ಲವನ್ನೂ ವ್ಯವಸ್ಥಿತವಾಗಿ ನಡೆಸುತ್ತಿರುವ ಆ ಮಹಾ ಶಕ್ತಿ\n\nಯಾವುದು? ಹೀಗೆ ಚಿಂತನೆ ಮಾಡಿದಾಗ ನಮಗೆ ಒಂದು ವಿಷಯ ತಿಳಿಯುತ್ತದೆ-ಅದೇ ಕರ್ಮ ಸಿದ್ಧಾಂತ. ಈ\nಜೀವಜಾತವನ್ನು ಮತ್ತು ಜಡಪ್ರಪಂಚವನ್ನು ಸೃಷ್ಟಿ ಮಾಡುವ ಮೂಲ ಶಕ್ತಿ ಆ ಭಗವಂತ. ಅವನ ಕ್ರಿಯೆಯೇ\nನಿಜವಾದ ಕ್ರಿಯೆ. ಈ ಪ್ರಪಂಚದ ವೈವಿಧ್ಯಮಯವಾದ ಸೃಷ್ಟಿಯ ಮೂಲವನ್ನು ತಿಳಿದಾಗ ನಿಜವಾದ ಕರ್ಮ\nತಿಳಿಯುತ್ತದೆ. ನಾವೆಲ್ಲರೂ ಕೂಡಾ ಭಗವಂತ ಸೃಷ್ಟಿ ಮಾಡಿದ ಗೊಂಬೆಗಳು-ಆತ ಸೂತ್ರದಾರ. ನಮ್ಮ ಕ್ರಿಯೆ ಆ\nಸೂತ್ರದಾರನ ನಿಯಮಕ್ಕೆ ಬದ್ಧ. ಇಡೀ ವಿಶ್ವಚಕ್ರ ಭಗವಂತನ ಅಧೀನವಾಗಿ ತಿರುಗುತ್ತಿದೆ. ಭಗವಂತನ ಕ್ರಿಯೆ\nಮಹಾಕ್ರಿಯೆ. ನಮ್ಮ ಕ್ರಿಯೆ -ಸುತ್ತುತ್ತಿರುವ ಮಹಾ ಚಕ್ರದ ಮೇಲೆ ಚಲಿಸುತ್ತಿರುವ ಇರುವೆಯಂತೆ. ಇರುವೆ ಯಾವ\nದಿಕ್ಕಿಗೆ ಚಲಿಸಿದರೂ ಕೂಡಾ ಅದು ಚಲಿಸುವುದು ಚಕ್ರ ತಿರುಗಿದಂತೇ ಹೊರತು ಇರುವೆ ಚಲಿಸಿದಂತೆ. ಚಕ್ರ\nತಿರುಗುವುದಿಲ್ಲ. ಅದೇ ರೀತಿ ಪ್ರಪಂಚದ ಗತಿ ನಮ್ಮ ಕ್ರಿಯೆಯ ಮೇಲೆ ನಿರ್ಧಾರವಲ್ಲ. ಅದು ತನ್ನ\nಗತಿಗನುಗುಣವಾಗಿ ನಿರಂತರ ನಡೆಯುತ್ತಿರುತ್ತದೆ. ಆದ್ದರಿಂದ “ನಾನು ಮಾಡಿದೆ' “ನನ್ನಿಂದಾಯ್ತು' ಎಂದು\nಅಹಂಕಾರ ಪಡುವುದರಲ್ಲಿ ಯಾವ ಅರ್ಥವೂ ಇಲ್ಲ. ಹೀಗೆ ಜೀವ ಜಡ ಪ್ರಪಂಚ ಸೃಷ್ಟಿಗೆ ಕಾರಣವಾಗಿರತಕ್ಕಂತಹ\nವಿಶಿಷ್ಟವಾದ ಸೃಷ್ಠಿ ಕ್ರಿಯೆಯೇ ನಿಜವಾದ 'ಕರ್ಮ'.\n\nಈ ಶ್ಲೋಕವನ್ನು ಇನ್ನೊಂದು ಆಯಾಮದಲ್ಲಿ ನೋಡಿದಾಗ ಇದು ಹೊಸ ರೀತಿಯಲ್ಲಿ ತೆರೆದುಕೊಳ್ಳುತ್ತದೆ. ಇಲ್ಲಿ\nಜೀವ ಬರುವುದೇ ಇಲ್ಲ. ಎಲ್ಲಾ ಮೂರೂ ಸಂಗತಿಗಳೂ ಭಗವಂತನನ್ನು ಹೇಳುತ್ತವೆ. ಬ್ರಹ್ಮ ಎಂದರೆ 'ಭಗವಂತ' ;\nಸ್ವಭಾವ ಅಂದರೆ ಭಗವಂತನ ಸ್ವತಂತ್ರ ಭಾವ. ಆದ್ದರಿಂದ ಭಗವಂತನ ಗುಣ-ಧರ್ಮ ಚಿಂತನೆಯೇ ಅಧ್ಯಾತ್ಮ.\nನಮ್ಮಲ್ಲಿ ಕೆಲವರು ಕೇಳುವುದಿದೆ. “ಭಗವಂತನಿಗೆ ಏಕೆ ಈ ಸ್ವಭಾವ ? ಒಬ್ಬರಿಗೆ ಸುಖ, ಒಬ್ಬರಿಗೆ ದುಃಖ,\nಒಬ್ಬರಿಗೆ ಬಡತನ, ಒಬ್ಬರಿಗೆ ಸಿರಿತನ, ಒಬ್ಬರು ನರಕಕ್ಕೆ, ಒಬ್ಬರು ಸ್ವರ್ಗಕ್ಕೆ , ಏಕೆ ಈ ತಾರತಮ್ಯ ಇ” ಎಂದು.\nಇದು ಬಾಲಿಷ ಪ್ರಶ್ನೆ. ಇಂತಹ ವಾದದಿಂದಲೇ ನಮ್ಮಲ್ಲಿ ನಾಸ್ತಿಕತೆ ಹುಟ್ಟಿಕೊಂಡಿರುವುದು. ಜೀವ ಅನಾದಿನಿತ್ಯ,\nಅದನ್ನು ಭಗವಂತ ಸೃಷ್ಟಿ. ಮಾಡುವುದಿಲ್ಲ. ಪ್ರತಿಯೊಂದು ಜೀವಸ್ವರೂಪದ ಗುಣಧರ್ಮ\nಸ್ವಭಾವಕ್ಕನುಗುಣವಾಗಿ, ಅರ್ಹತೆಗನುಗುಣವಾಗಿ, ಅವರವರನ್ನು ಸೃಷ್ಟಿ ಮಾಡುವುದು ಭಗವಂತನ ಸ್ವಭಾವ.\nಆದ್ದರಿಂದ ಇಲ್ಲಿ ತಾರತಮ್ಯ ಅನ್ನುವ ಪ್ರಶ್ನೆಯೇ ಇಲ್ಲ. ಭಗವಂತನ ಸೃಷ್ಟಿಯ ಹಿಂದಿರುವ ಆತನ ಸ್ವಾತಂತ್ರ್ಯ;\nನಿಷ್ಪಕ್ಷಪಾತ; ಯಾವುದೇ ಪ್ರಭಾವಕ್ಕೊಳಗಾಗದಿರುವುದು; ತ್ರಿಗುಣಾತೀತತ್ವ-ಇವು ಭಗವಂತನ ಮೂಲಭೂತ\nಸ್ವಭಾವ. ಇದರ ಅರಿವೇ “ಅಧ್ಯಾತ್ಮ'. ಭಗವಂತನ ಗುಣಧರ್ಮವನ್ನು ತಿಳಿದಾಗ ಅವನ ಸೃಷ್ಟಿ ಏನು ಎಂದು\nಅರ್ಥವಾಗುತ್ತದೆ. ಅದೇ ಕರ್ಮ. ಭಗವಂತನ ಕ್ರಿಯೆಯಲ್ಲಿ ಜ್ಞಾನ-ಇಚ್ಚೆ-ಕೃತಿ ಎನ್ನುವ ಮೂರು ಹಂತವಿಲ್ಲ. ಆತ\nಇಚ್ಚಿಸುವುದೇ ಕ್ರಿಯೆ. ಇದನ್ನು ತಿಳಿಯುವುದು “ಕರ್ಮದ ಅರಿವು'. ಹೀಗೆ ಭಗವಂತನ ಸ್ವರೂಪದ, ಗುಣಧರ್ಮದ\nಮತ್ತು ಕ್ರಿಯೆಯ ಅರಿವೇ -ಬ್ರಹ್ಮ ಅಧ್ಯಾತ್ಮ ಮತ್ತು ಕರ್ಮ.",
  "8.4": "ಅಧಿಭೂತಮ್‌ ಕ್ಷರಃ ಭಾವಃ ಪುರುಷಃ ಚ ಅಧಿದೈವತಮ್‌ |\n\nಅಧಿಯಜ್ಞಃ ಅಹಮ್‌ ಏವ ಅತ್ರ ದೇಹೇ ದೇಹಭೃತಾಮ್‌ ವರ- ಹುಟ್ಟಿ ಸಾಯುವ ಸಮಷ್ಟಿ ಬ್ರಹ್ಮಾಂಡ\n[ದೇಹೆಂದ್ರಿಯಗಳಿಂದ ಕೂಡಿದ ಜೀವರಾಶಿ] \"ಅಧಿಭೂತ', ಶರೀರದೊಳಗಿದ್ದು ನಿಯಮಿಸುವ ತತ್ತ್ವಾಭಿಮಾನಿ\nದೇವತೆಗಳು[ಜಗತ್ತಿನ ಹಿರಿಯ ಚಾಲಶಶಕ್ತಿಯಾಗಿ “ಪುರುಷ' ಎನಿಸಿದ ಶ್ರೀತತ್ವ ] 'ಅಧಿದೈವ'. ಹಿರಿಯ ಜೀವವೇ,\nಈ ದೇಹದಲ್ಲಿ ನಾನೇ “ಅಧಿಯಜ್ಞ'.\n\nಹಿಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ನೋಡಿದಂತೆ ಅಧ್ಯಾತ್ಮ ಎಂದರೆ ಶರೀರದಲ್ಲಿ ಬಂಧಿಯಾಗಿರುವ ಜೀವ. ಈ ಜೀವದ\nಭೋಗಕ್ಕಾಗಿ ಸೃಷ್ಟಿಯಾಗಿರತಕ್ಕಂತಹ ಪಂಚಭೂತಾತ್ಮಕವಾದ ಈ ಪ್ರಪಂಚದ ಸಮಸ್ತ ವಿಚಾರಗಳೂ\nಅಧಿಭೂತದಲ್ಲಿ ಸೇರಿದೆ. ಪಂಚಭೂತದ ಮೂಲದ್ರವ್ಯ ಮತ್ತು ಪಂಚಭೂತದಿಂದ ನಿರ್ಮಾಣಗೊಂಡ ಪ್ರಪಂಚ\nಅಧಿಭೂತ. ಜಡ ಪ್ರಕೃತಿಯಿಂದ ಹಿಡಿದು ಸ್ಥೂಲ ವಿಶ್ವದ ತನಕ ತ್ರಿಗುಣಾತ್ಮಕವಾದ ಎಲ್ಲವೂ 'ಅಧಿಭೂತ'.\n\nಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ. “ಪುರುಷಶ್ಚಾಧಿದೈವತಮ್‌” ಎಂದು. ಈ ಶರೀರದೊಳಗಿರುವ ಜೀವಕ್ಕೆ\nನೆರವಾಗುವುದಕ್ಕೋಸ್ಕರ ದೇಹದಲ್ಲಿ ಬೇರೆ ಬೇರೆ ಇಂದ್ರಿಯಗಳನ್ನು ನಿಯಂತ್ರಿಸತಕ್ಕಂತಹ ದೇವತೆಗಳಿದ್ದಾರೆ.\nಇದು ಅಧಿದೈವತಾ ವಿಜ್ಞಾನ. ಇದು ಒಂದು ಮುಖ. ಇನ್ನೊಂದು ರೀತಿಯಲ್ಲಿ ನೋಡಿದರೆ ಇಲ್ಲಿ ಕೃಷ್ಣ \"ಪುರುಷ'\nಎಂದು ಸಂಬೋಧಿಸಿದ್ದಾನೆ. ನಮ್ಮ ದೇಹದಲ್ಲಿ ನಾಲ್ಕು \"ಪುರುಷರಿದ್ದಾರೆ'. ಶರೀರಪುರುಷ, ಛಂದಃಪುರುಷ,\nವೇದಪುರುಷ ಮತ್ತು ಸಂವತ್ಸರಪುರುಷ. ಈ ದೇಹ ನಿಂತು ನಡೆದಾಡಬೇಕಾದರೆ ದೇಹದಲ್ಲಿ ಶರೀರಪುರುಷನಾದ\nಶಿವಶಕ್ತಿ ಬೇಕು. ಮನಸ್ಸು ಯೋಚಿಸಿದ್ದನ್ನು ಸ್ಪಂದನ, ಪರಾಶರ, ಪಶ್ಯಂತಿ, ಮದ್ಯಮ ಮತ್ತು ವೈಖರಿ ರೂಪದಲ್ಲಿ\nವಾಕ್‌ ಶಕ್ತಿ ಯಾಗಿ ಹೊರಹೊಮ್ಮಲು ಛಂದಃಪುರುಷನಾದ ಶೇಷ ಕಾರಣ. ಮನೋಮಯ ಕೋಶದಲ್ಲಿದ್ದು,\nವೇದಾಂತದ ಚಿಂತನೆ, ಮನಸ್ಸಿನಲ್ಲಿ ಮನನ ಶಕ್ತಿ ಕೊಡತಕ್ಕವ ವೇದಪುರುಷ ಗರುಡ. ವೇದಪುರುಷ ನಮಗೆ\nಅಪೂರ್ವವಾದ ವೈದಿಕ ವಾಜ್ಮಯ ಶಕ್ತಿ ಪ್ರಾಪ್ತವಾಗುವಂತೆ ಮಾಡುತ್ತಾನೆ. ಜೀವದ ಯೋಗ್ಯತೆಯನ್ನು, ಇಡೀ\nಜೀವದ ಸ್ವರೂಪವನ್ನು ನಿಯಂತ್ರಣ ಮಾಡುವವ ಜೀವಕಲಾಭಿಮಾನಿ ಚತುರ್ಮುಖಬ್ರಹ್ಮ, ಈತ\nಸಂವತ್ಸರಪುರುಷ. [ “ಸಂ-ವತ್ಸ-ರ'- ಅಂದರೆ ಚೆನ್ನಾಗಿ ಮಕ್ಕಳನ್ನು ಸಾಕುವ ಪಿತಾಮಹ]. ಬ್ರಹ್ಮ-ವಾಯು\nಜೀವನನ್ನು ಮೇಲಕ್ಕೆತ್ತಿ ಸಾಧನೆಯ ಹಾದಿಯಲ್ಲಿ ತೊಡಗಿಸುತ್ತಾರೆ. ಹೀಗೆ ಈ ಪಂಚದೇವತೆಗಳು ಭಗವಂತನ\nನಂತರ ದೇಹದಲ್ಲಿರುವ ಪ್ರಮುಖ ಅಧಿದೇವತೆಗಳು. ಅವರಿಂದ ನಿಯಂತ್ರಿಸಲ್ಪಟ್ಟ ಸಮಸ್ತ ಬ್ರಹ್ಮಾಂಡ\nಅಧಿಭೂತ.\n\nಕೃಷ್ಣ ಮುಂದುವರಿದು ಹೇಳುತ್ತಾನೆ: ಪ್ರತಿಯೊಂದು ದೇಹದ ಒಳಗೂ ನಾನು ಒಂದೊಂದು ರೂಪದಲ್ಲಿದ್ದೇನೆ\nಎಂದು. ಭಗವಂತನ ಈ ರೂಪವೇ “ಅಧಿಯಜ್ಞ' ರೂಪ. ಯಜ್ಞವನ್ನು ಅಧಿಕರಿಸಿ, ಅದನ್ನು ನಿಯಂತ್ರಿಸುವ ಯಜ್ಞ\nಭೋಕ್ತಾರ, ಯಜ್ಞವನ್ನು ಮಾಡುವವ, ಮಾಡಿಸುವವ, ಮತ್ತು ಫಲಪ್ರದನಾದ ಭಗವಂತ ಅಧಿಯಜ್ಞ. ನಾವು\nಭಗವಂತನ ಪೂಜಾರೂಪ ಎಂದು ತಿಳಿದು ಮಾಡುವ ಎಲ್ಲಾ ಕರ್ಮವೂ ಯಜ್ಞ. \"ಯಜ ದೇವಾ ಪೂಜಾಯಾಂ' -\nನಮ್ಮ ಬದುಕಿನ ಪ್ರತಿಯೊಂದು ಕ್ರಿಯೆಯೂ ಭಗವಂತನ ಆರಾಧನೆ. ನಮ್ಮ ದೇಹದೊಳಗಿದ್ದು, ಸಕಲ\nತತ್ತ್ವಾಭಿಮಾನಿ ದೇವತೆಗಳ ಮುಖೇನ ಕ್ರಿಯೆ ಮಾಡಿಸುವ ಭಗವಂತ \"ಅಧಿಯಜ್ಞ'.\n\nಎರಡನೇ ಆಯಾಮದಲ್ಲಿ ಈ ಶ್ಲೋಕವನ್ನು ನೋಡಿದರೆ [ಹಿಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ಭಗವಂತ-ಭಗವಂತನ ಸ್ವಭಾವ\nಮತ್ತು ಅವನ ಕ್ರಿಯೆ ಎನ್ನುವ ಅರ್ಥ ವಿಶ್ಲೇಷಣೆಯಂತೆ]1 ಅಧಿಭೂತ ಎಂದರೆ ಬ್ರಹ್ಮಾದಿಸಮಸ್ತ ದೇವತೆಗಳು.\nಚೇತನಾಚೇತನಾತ್ಮಕ ಪ್ರಪಂಚ, ಜೀವರು, ಶರೀರ, ಬ್ರಹ್ಮ ಮತ್ತು ಬ್ರಹ್ಮಾಂಡ ಎಲ್ಲವೂ ಅಧಿಭೂತ. ಎಲ್ಲಾ\nದೇವತೆಗಳಿಗೂ ಮಿಗಿಲಾದ ಭಗವಂತನ ಅನಂತರ ಬ್ರಹ್ಮಾದಿ ದೇವತೆಗಳಿಗೂ ತಾಯಿಯಾದ “ಶಕ್ತಿ” ಶ್ರೀತತ್ತ್ವ\nಅಧಿದೈವ. ಎಲ್ಲೆಡೆ ತುಂಬಿದ್ದು ಎಲ್ಲಾ ಜೀವರ ಒಳಗೆ ಅಂತರ್ಯಾಮಿಯಾಗಿ ನಿಂತು ನಿಯಮಿಸುವ ಭಗವಂತ\nಅಧಿಯಜ್ಞ.\n",
  "8.5": "ಅಂತಕಾಲೇ ಚ ಮಾಮ್‌ ಏವ ಸ್ಮರನ್‌ ಮುಕ್ತ್ವಾ ಕಳೇಬರಮ್‌ |\n\nಯಃ ಪ್ರಯಾತಿ ಸಃ ಮತ್‌ ಭಾವಮ್‌ ಯಾತಿ ನ ಅಸ್ತಿ ಅತ್ರ ಸಂಶಯಃ -ಕೊನೆಯ ಕಾಲದಲ್ಲೂ ನನ್ನನ್ನೇ\nನೆನೆಯುತ್ತಾ ದೇಹವನ್ನು ತೊರೆದು ತೆರಳುವವನು ನನ್ನಂತಯೇ ದುಃಖವಿರದ ಸುಖದ ನಿಜಸ್ಥಿತಿಯನ್ನು [ನನ್ನಲ್ಲೇ\nಇರವನ್ನು] ಪಡೆಯುತ್ತಾನೆ.\n\nಅರ್ಜುನನ ಕೊನೆಯ ಪ್ರಶ್ನೆಗೆ ಕೃಷ್ಣ ಉತ್ತರಿಸುತ್ತಾ ಹೇಳುತ್ತಾನೆ: “ಸಾಯುವ ಕ್ಷಣದಲ್ಲೂ ಕೂಡಾ ನನ್ನನ್ನೇ\nನೆನ",
  "8.6": "ಯಮ್‌ ಯಮ್‌ ವಾ ಅಪಿ ಸ್ಮರನ್‌ ಭಾವಮ್‌ ತ್ಯಜತಿ ಅಂತೇ ಕಳೇಬರಮ್‌ |\n\nತಮ್‌ ತಮ್‌ ಏವ ಏತಿ ಕೌಂತೇಯ ಸದಾ ತತ್‌ ಭಾವ ಭಾವಿತಃ -- ಕೌಂತೇಯಾ, ಕೊನೆಯಲ್ಲಿ ಯಾವ ಯಾವ\nವಿಷಯವನ್ನು ನೆನೆಯುತ್ತಾ ದೇಹವನ್ನು ತೊರೆಯುತ್ತಾನೇ ಅದರಲ್ಲೇ ಅನುಗಾಲ ಬೇರೂರಿದ ಸಂಸ್ಕಾರದಿಂದ\nಅದನ್ನೆ ಪಡೆಯುತ್ತಾನೆ.\n\n“ಜೀವನ ಯಾತ್ರೆಯ ಅಂತಿಮ ಕ್ಷಣದಲ್ಲಿ ಭಗವಂತನನ್ನು ನೆನೆದವರು “ನನ್ನನ್ನು' ಸೇರುತ್ತಾರೆ” ಎಂದು ಕೃಷ್ಣ ಏಕೆ\nಹೇಳಿದ ಎನ್ನುವುದಕ್ಕೆ ಈ ಶ್ಲೋಕದಲ್ಲಿ ಉತ್ತರವಿದೆ. ಇಲ್ಲಿ ಕೃಷ್ಣ ಮರಣ ಕಾಲದ ಒಂದು ಅದ್ಭುತ\nಮನಃಶಾಸ್ತ್ರವನ್ನು ನಮ್ಮ ಮುಂದೆ ತೆರೆದಿಡುತ್ತಾನೆ. ಸಾಯುವ ಕ್ಷಣದಲ್ಲಿ ಭಗವಂತನ ಧ್ಯಾನ ಮಾಡಲು ಒಂದು\nಉದ್ದೇಶವಿದೆ ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ನಾವು ದೇಹ ತ್ಯಾಗ ಮಾಡುವಾಗ ಏನನ್ನು ಸ್ಮರಣೆ ಮಾಡುತ್ತೇವೋ ಮುಂದಿನ\nಜನ್ಮದಲ್ಲಿ ಅದನ್ನೇ ಪಡೆಯುತ್ತೇವೆ. ಆದ್ದರಿಂದ ಆ ಕಾಲದಲ್ಲಿ ಭಗವಂತನನ್ನು ಸ್ಮರಿಸಿದರೆ ಭಗವಂತನನ್ನು\nಸೇರುತ್ತೇವೆ. ಸಾವಿನ ಕೊನೇ ಕ್ಷಣದಲ್ಲಿ ಬರುವ ಚಿಂತನೆ ಮುಂದಿನ ಜನ್ಮದ ನಿರ್ಣಾಯಕ ಸಂಗತಿ. ಹಾಗಾಗಿ\nಮುಂದಿನ ಜನ್ಮದಲ್ಲಿ ಆತ ಏನಾಗಬೇಕೋ ಅದೇ ನೆನಪಾಗುತ್ತದೆ! ಭಗವಂತನನ್ನು ಸೇರುವ ಯೋಗ\nಇಲ್ಲದವರಿಗೆ ಭಗವಂತನ ನೆನಪು ಬರುವುದೇ ಇಲ್ಲ! ಇದಕ್ಕೆ ಶಾಸ್ತ್ರದಲ್ಲಿ ಅನೇಕ ದೃಷ್ಟಾಂತಗಳಿವೆ. ಈ ದೇಶಕ್ಕೆ\n'ಭಾರತ' ಎಂದು ಹೆಸರು ಬರಲು ಕಾರಣನಾದ ವೃಷಭದೇವನ ಮಗ ಭರತನ ಕಥೆ ಈ ವಿಚಾರವನ್ನು ಸ್ಪಷ್ಟವಾಗಿ\nಹೇಳುವ ಕಥೆ. (ಈ ಭರತ ದುಃಷಂತನ ಮಗ ಭರತನಲ್ಲ, ದುಃಷಂತನ ಮಗ ಭರತ 'ಭರತವಂಶ' ದ ಮೂಲ\nಪುರುಷ). ಪರಮ ಧಾರ್ಮಿಕನಾದ ಭರತ ತನ್ನ ಮಗ ಪ್ರಾಯ ಪ್ರಬುದ್ಧನಾದ ಮೇಲೆ ತನ್ನೆಲ್ಲಾ ಅಧಿಕಾರವನ್ನು\nಅವನಿಗೊಪ್ಪಿಸಿ, ವಾನಪ್ರಸ್ಥಾಶ್ರಮವನ್ನು ಸ್ವೀಕರಿಸಿ ಕಾಡಿನಲ್ಲಿ ಋಷಿಗಳ ಜೊತೆಗೆ ಸದಾ ಭಗವದ್‌ ನಿಷ್ಠನಾಗಿ\nಬದುಕುತ್ತಿದ್ದ. ಒಂದು ದಿನ ಆತನಿಗೆ ಕಾಡಿನಲ್ಲಿ ತಾಯಿ ಸತ್ತ ಒಂದು ಜಿಂಕೆ ಮರಿ ಸಿಕ್ಕಿತು. ಭರತ ಆ ಮರಿಯನ್ನು\nತಂದು ಪಾಲನೆ ಪೋಷಣೆ ಮಾಡತೊಡಗಿದ. ಇದರಿಂದ ಆತ ಸದಾ ಆ ಜಿಂಕೆಯನ್ನೇ ಪೋಷಣೆ ಮಾಡುವುದರಲ್ಲಿ\nತನ್ನ ಸಮಯವನ್ನು ಕಳೆಯಲಾರಂಭಿಸಿದ. ಇದರಿಂದ ಆತನ ಸಾಧನೆಗೆ ಚ್ಯುತಿ ಬಂತು. ಆ ಜಿಂಕೆಯ ಮರಿ\nಬೆಳೆದು ದೊಡ್ಡದಾಗುವ ಮೊದಲೇ ಆತ ಪ್ರಾಣತ್ಯಾಗ ಮಾಡುವ ಪ್ರಸಂಗ ಬಂತು. ಆ ಕಾಲದಲ್ಲಿ ಭರತನಿಗೆ\nಭಗವಂತನ ಚಿಂತನೆಯ ಬದಲು ಕಾಡಿದ್ದು ಆ ಜಿಂಕೆ ಮರಿಯ ಚಿಂತೆ! ಇದರಿಂದ ಆತ ತನ್ನ ಮುಂದಿನ ಜನ್ಮದಲ್ಲಿ\nಜಿಂಕೆಯಾಗಿ ಹುಟ್ಟಿದ. ಆದ್ದರಿಂದ ಎಂತಹ ಅಪರೋಕ್ಷ ಜ್ಞಾನಿಯನ್ನೂ ಕೂಡಾ ಪ್ರರಾಬ್ಧ ಬಿಡದು ಎನ್ನುವುದಕ್ಕೆ\nಇದು ಶ್ರೇಷ್ಠ ಉದಾಹರಣೆ. ಈ ಕಥೆ ಕೃಷ್ಣ ಇಲ್ಲಿ ಹೇಳುವ ವಿಚಾರಕ್ಕೆ ಜ್ವಲಂತ ದೃಷ್ಟಾಂತ.\n\nನಾವು ಜೀವನ ಪರ್ಯಂತ ಸಾಧನೆ ಮಾಡಿದರೂ ಕೂಡಾ, ಸಾಯುವ ಕ್ಷಣದಲ್ಲಿ ಭಗವಂತನ ನೆನಪು ಬಾರದೇ\nಹೋಗಬಹುದು. ಇದಕ್ಕಾಗಿ ಜೀವನ ಪರ್ಯಂತ ಅಥವಾ ಅನೇಕ ಜನ್ಮಗಳ ಸಾಧನೆ ಅಗತ್ಯ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ\n“ಸದಾ ತದ್‌ ಭಾವಭಾವಿತಃ” ಎಂದು. ಇಲ್ಲಿ ಭಾವ ಎಂದರೆ ತನ್ಮಯತೆ. ಯಾವಾಗಲೂ ಭಗವಂತನಲ್ಲೇ\nತನ್ಮಯವಾದ ಮನಸ್ಸಿನಿಂದ ನಿರಂತರ ಭಗವಂತನ ಚಿಂತನೆ ಮಾಡಬೇಕು. ಅಂತ್ಯ ಕಾಲದಲ್ಲಿ ಭಗವಂತನ\nನೆನಪು ಬರಬೇಕಾದರೆ, ನಿರಂತರ ಭಗವಂತನಲ್ಲಿ ಮನಸ್ಸನ್ನು ನೆಲೆಗೊಳಿಸುವ ಸಂಸ್ಕಾರ ಬೇಕು. ಇದನ್ನು ಬಿಟ್ಟು\nಮರಣ ಕಾಲದಲ್ಲಿ ಭಗವಂತನನ್ನು ನೆನೆದರಾಯ್ತು ಎಂದು ಜೀವನವನ್ನು ವ್ಯರ್ಥವಾಗಿ ಕಳೆದರೆ ಮರಣ ಕಾಲದಲ್ಲಿ\nಭಗವಂತನ ನೆನಪು ಬರುವುದೇ ಇಲ್ಲ!\n\nಭೀಷ್ಮಾಚಾರ್ಯರಿಗೆ ಕೊನೆಗಾಲದಲ್ಲಿ ಎಷ್ಟೇ ಭಗವಂತನ ಬಗ್ಗೆ ಯೋಚಿಸಿದರೂ ಕೂಡಾ ಕಂಡಿದ್ದು ತನ್ನದೇ\nಬಾಣದಿಂದ ಗಾಯಗೊಂಡು ನೆತ್ತರು ಸುರಿಸುತ್ತಿರುವ ಕೃಷ್ಣ! ಆನಂದಸ್ವರೂಪ ಭಗವಂತನ ನಿಜ ದರ್ಶನ\nಅವರಿಗಾಗಲಿಲ್ಲ. ಇಲ್ಲಿ ನಾವು ಅರಿಯಬೇಕಾದ ವಿಚಾರವೇನೆಂದರೆ-ನಾವು ಯಾವುದೇ ಕೆಟ್ಟ ಸಂಗತಿಯನ್ನು\nಗಾಢವಾಗಿ ಮನಸ್ಸಿಗೆ ಹಚ್ಚಿಕೊಳ್ಳಬಾರದು. ಹಚ್ಚಿಕೊಂಡರೆ ಕೊನೆಗಾಲದಲ್ಲಿ ಅದೇ ಕಾಣುತ್ತದೆ! ಇಡೀ ಜೀವನದಲ್ಲಿ\nನಾವು ಯಾವತ್ತೂ ಕೆಟ್ಟದ್ದನ್ನು ಯೋಚಿಸಬಾರದು. ಯಾರನ್ನೂ ಕೆಟ್ಟವರೆಂದು ದ್ವೇಷಿಸಬಾರದು. ಒಬ್ಬರನ್ನು\n\nದ್ವೇಷಿಸುವುದು ತುಂಬಾ ಕೆಟ್ಟದ್ದು. ಅದು ನಮ್ಮ ಇಡೀ ಬದುಕನ್ನೇ ಹಾಳುಮಾಡುತ್ತದೆ. ದುಷ್ಟರಿಂದ ದೂರವಿರು\nಆದರೆ ದ್ವೇಷಿಸಬೇಡ. ಒಬ್ಬರನ್ನು ದ್ವೇಷಿಸುವುದು, ನಿಂದಿಸುವುದು, ಅದನ್ನು ಗಾಢವಾಗಿ ಹಚ್ಚಿಕೊಳ್ಳುವುದರಿಂದ\nಅವರಿಗೆ ಏನೂ ಬಾಧಕವಿಲ್ಲ. ಆದರೆ ನಮ್ಮ ಬದುಕನ್ನು ನಾವು ಹಾಳು ಮಾಡಿಕೊಳ್ಳುತ್ತೇವೆ. ನಾವು ದ್ವೇಷಿಸುವ\nವಸ್ತು ನಮ್ಮ ತಲೆಯಲ್ಲಿ ಗಾಢವಾಗಿ ನೆಲೆ ನಿಲ್ಲುತ್ತದೆ ಮತ್ತು ನಮ್ಮನ್ನು ಅಧಃಪಾತಕ್ಕೆ ಕೊಂಡೊಯ್ಯುತ್ತದೆ. ಅದು\nಸಾವಿನ. ಕಾಲದಲ್ಲಿ ಕೊನೆಗೆ ತಲೆಎತ್ತಿ ಹೆಡೆ ಅರಳಿಸುತ್ತದೆ! ಆದ್ದರಿಂದ ನಾವು ಈ ವಿಚಾರದಲ್ಲಿ\nಎಚ್ಚರವಾಗಿರಬೇಕು. ಯಾರನ್ನಾದರು ಟೀಕೆ ಮಾಡಲು ನಾವು ಅರ್ಹರಲ್ಲ. ಏಕೆಂದರೆ ನಮಗೆ ಅಂತರಂಗ\nದರ್ಶನವಿಲ್ಲ. ನಾವು ಮಾತನಾಡುವುದು ಕೇವಲ ಹೊರ ನೋಟದಿಂದ. ಒಳಗೆ \"ಯಾರು ಏನು' ಎಂದು ನೋಡುವ\nಶಕ್ತಿ ನಮಗಿಲ್ಲ. ಆದ್ದರಿಂದ ಇನ್ನೊಬ್ಬರ ಚಿಂತನೆ ಬಿಟ್ಟು ಸದಾ ಭಗವಂತನ ಚಿಂತನೆ ಮಾಡು ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.\nನಾವು ಚಿಂತಿಸಬೇಕಾದ ಏಕಮಾತ್ರ ವಸ್ತು ಕೇವಲ ಭಗವಂತ.",
  "8.7": "ತಸ್ಮಾತ್‌ ಸರ್ವೇಷು ಕಾಲೇಷು ಮಾಮ್‌ ಅನುಸ್ಮರ ಯುಧ್ಯ ಚ।\n\nಮಯಿ ಅರ್ಪಿತ ಮನಃ ಬುದ್ಧಿಃ ಮಾಮ್‌ ಏವ ಏಷ್ಯಸಿ ಅಸಂಶಯಃ -ಆದ್ದರಿಂದ ಎಲ್ಲಾ ಕಾಲದಲ್ಲೂ ನನ್ನನ್ನು ನೆನೆ.\nನೆನೆಯುತ್ತಾ ಹೋರಾಡು. ನಿನ್ನೆಲ್ಲಾ ಬಯಕೆ ನಿರ್ಧಾರಗಳು ನನ್ನ ಕುರಿತಾದಾಗ ನಿಶ್ಚಯವಾಗಿ ನನ್ನನ್ನೇ\nಸೇರುವೆ.\n\nದೇವರನ್ನು ಸ್ಮರಣೆ ಮಾಡುವ ಕಾಲ ಅಂತ ಒಂದಿಲ್ಲ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ಸರ್ವ ಕಾಲದಲ್ಲೂ ನನ್ನನ್ನು ಸ್ಮರಣೆ\nಮಾಡು” ಎಂದು. ಪ್ರತಿಯೊಂದು ಕ್ರಿಯೆ ಮಾಡುವಾಗ ಆ ಕ್ರಿಯೆ ಮಾಡಿಸುತ್ತಿರುವವ ಭಗವಂತ ಎನ್ನುವ\nಎಚ್ಚರವಿರಲಿ. ಯುದ್ಧ ಮಾಡುವಾಗಲೂ ಸಹ “ಆ ಭಗವಂತ ನನ್ನೊಳಗೆ ಕೂತು ಈ ಕಾರ್ಯವನ್ನು\nಮಾಡಿಸುತ್ತಿದ್ದಾನೆ, ಇದು. ಅವನ ಸಂಕಲ್ಪ” ಎನ್ನುವ ಭಾವನೆ ಯುದ್ಧವನ್ನೂ ದೇವರ ಪೂಜೆಯನ್ನಾಗಿ\nಪರಿವರ್ತಿಸುತ್ತದೆ! ನಮ್ಮಿಂದ ತಿಳಿದೋ ತಿಳಿಯದೆಯೋ ಆಗುವ ತಪ್ಪಿನಲ್ಲಿಯೂ ಕೂಡಾ ಭಗವಂತನ ಅರಿವು,\nಶರಣಾಗತಿ ನಮಗೆ ಪಾಪದ ಲೇಪ ಬರದಂತೆ ತಡೆಯುತ್ತದೆ. ಭಗವಂತನ ಸ್ಮರಣೆಗೆ ಯಾವುದೇ ಕಾಲದ\nನಿರ್ಬಂಧವಿಲ್ಲ... ಯಾವಾಗ ಭಗವಂತನ ಸ್ಮರಣೆ ಬಂತೋ ಅದೇ ಪುಣ್ಯಕಾಲ. ಆತನ ಸ್ಮರಣೆ\nಮನಸ್ಸಿನಲ್ಲಿರುವುದೇ ಮಡಿ. ಆದ್ದರಿಂದ ಭಗವಂತನ ಪೂಜಾರೂಪವಾಗಿ ಅಹಂಕಾರವಿಲ್ಲದೆ ಆತನನ್ನು ನೆನೆದು\nಕರ್ತವ್ಯ ಮಾಡಬೇಕು.\n\nಕ್ರಿಯೆಯಲ್ಲಿ ಇರತಕ್ಕ ಭಾವ ಧರ್ಮ-ಅಧರ್ಮವನ್ನು ನಿರ್ಣಯ ಮಾಡುತ್ತದೆ. ಉದಾಹರಣೆಗೆ ಧರ್ಮವ್ಯಾದ. ಈತ\nಮಾಂಸ ಮಾರಿಯೂ ಪರಮ ಧಾರ್ಮಿಕನಾಗಿ ಬದುಕಿದ. ಏಕೆಂದರೆ ಆತನ ಅನುಸಂಧಾನ ಶುದ್ಧವಾಗಿತ್ತು.\n“ದೇವರು ನನ್ನನ್ನು ಈ ಕೆಲಸಕ್ಕೆ ಹಚ್ಚಿದ್ದಾನೆ, ನನ್ನ ಈ ಜನ್ಮದ ಕರ್ತವ್ಯ ಮಾಂಸ ಮಾರಿ ಬದುಕುವುದು. ಅದನ್ನು\nಪ್ರಾಮಾಣಿಕವಾಗಿ ಮಾಡಿ ಜೀವನ ಸಾಗಿಸಬೇಕು” ಎನ್ನುವ ಅನುಸಂಧಾನ ಆತನಲ್ಲಿತ್ತು. ಆತ ತನ್ನ\n\nವ್ಯಾಪಾರವನ್ನು ಕೇವಲ ತನ್ನ ಹಾಗೂ ತನ್ನ ಕುಟುಂಬದ ಜೀವನ ನಿರ್ವಹಣೆಗಾಗಿ ಮಾಡುತ್ತಿದ್ದ. ಈ ರೀತಿ\nಪ್ರಾಮಾಣಿಕನಾಗಿ ಬದುಕಿ ಆತ ಖುಷಿಗಳನ್ನೂ ಮೀರಿಸುವಷ್ಟು ಎತ್ತರಕ್ಕೇರಿದ. ಆದ್ದರಿಂದ ಭಾವ ಶುದ್ಧಿ ಅತ್ಯಂತ\nಶ್ರೇಷ್ಠ. ಹಾಗಾಗಿ ನಾವು ನಮ್ಮ ಮನಸ್ಸು ಮತ್ತು ಬುದ್ಧಿಯನ್ನು ಭಗವಂತನಲ್ಲಿ ನೆಲೆ ನಿಲ್ಲಿಸಬೇಕು. “ಆಗ\nನಿಸ್ಸಂಶಯವಾಗಿ ನನ್ನನ್ನು ಸೇರುವೆ” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.\n",
  "8.8": "ಅಭ್ಯಾಸ ಯೋಗ ಯುಕ್ತೇನ ಚೇತಸಾ ನ ಅನ್ಯ ಗಾಮಿನಾ |\n\nಪರಮಮ್‌ ಪುರುಷಮ್‌ ದಿವ್ಯಮ್‌ ಯಾತಿ ಪಾರ್ಥ ಅನುಚಿಂತಯನ್‌ -ಪಾರ್ಥಾ, ಸೃಷ್ಟಿಯೊಂದು ಲೀಲೆಯಾದ-\nಪರಮ ಪುರುಷನನ್ನು ಅಭ್ಯಾಸದ ಉಪಾಯದಿಂದ ಹದಗೊಂಡು, ಬೇರಾವುದೂ ಬೇಡದ ಒಳಬಗೆಯಿಂದ,\nಭಕ್ತಿಯಿಟ್ಟು ನೆನೆದಾಗ ಅವನನ್ನೇನ್ನೆ ಸೇರುತ್ತಾನೆ.\n\nನಾವು ನಮ್ಮ ಮನಸ್ಸನ್ನು ನಿರಂತರ ಭಗವಂತನಲ್ಲಿ ನೆಲೆ ನಿಲ್ಲುವಂತೆ ಮಾಡಲು \"ನಿರಂತರ ಮನನ' ಅತ್ಯಂತ\nಮುಖ್ಯ ಅಂಶ. ಸಾಮಾನ್ಯವಾಗಿ ನಮ್ಮ ಚಿತ್ತ ಬೇಡದ ವಿಷಯಗಳತ್ತ ಹರಿಯುತ್ತದೆ. ಆದರೆ ನಾವು ಅದನ್ನು\nಕೇವಲ ಭಗವಂತನನ್ನು ಚಿಂತಿಸುವಂತೆ ತರಬೇತಿಗೊಳಿಸಬೇಕು. ಚಿತ್ತಕ್ಕೆ ಭಗವಂತನನ್ನು ಅನನ್ಯಗಾಮಿಯಾಗಿ\nಚಿಂತನೆ ಮಾಡುವಂತೆ ನಿರಂತರ ಅಭ್ಯಾಸ ಮಾಡಿಸಬೇಕು. ನಮ್ಮ ಮನಸ್ಸು, ಬುದ್ಧಿ, ಚಿತ್ತ ಎಲ್ಲವೂ ನಾವು\nಅಭ್ಯಾಸ ಮಾಡಿಸಿದಂತೆ ಕೆಲಸ ಮಾಡುತ್ತವೆ. ಅವುಗಳಿಗೆ ನಾವು ಭಗವಂತನ ಚಿಂತನೆಯ ಅಭ್ಯಾಸ\nಮಾಡಿಸಬೇಕು. ಮನಸ್ಸು ಚಿತ್ತವನ್ನು ಮಣಿಸುವ ಏಕಮಾತ್ರ ಸಾಧನ ಅಭ್ಯಾಸ. ಹೀಗೆ ಮಾಡಿದಾಗ ಅದು\nಭಗವಂತನಲ್ಲಿ ನೆಲೆನಿಲ್ಲುತ್ತದೆ. ಭಗವಂತನಲ್ಲಿ ನೆಲೆನಿಂತ ಮನಸ್ಸು ಅಂತ್ಯಕಾಲದಲ್ಲಿ ಕೂಡಾ ಭಗವಂತನನ್ನೇ\nಕಾಣುತ್ತದೆ. ಇದು. ಕೇವಲ ಚಿಂತನೆ ಅಲ್ಲ ಇದು ಅನುಚಿಂತನೆ-ಅಂದರೆ ಭಗವಂತನ ಯಥಾರ್ಥ\n(ಯತಾವತ್ತಾದ)ಚಿಂತನೆ. ಶ್ರುತಿಯಲ್ಲಿ ಹೇಗೆ ಹೇಳಿದ್ದಾರೋ ಹಾಗೇ ಭಗವಂತನನ್ನು ಚಿಂತನೆ ಮಾಡಬೇಕು.\nಅಸತ್ಯವನ್ನು ಚಿಂತನೆ ಮಾಡಿ ಭಗವಂತನನ್ನು ಸೇರಲು ಸಾಧ್ಯವಿಲ್ಲ.\n\nಏಕಾಗ್ರವಾದ ಮನಸ್ಸಿನಿಂದ ದಿವ್ಯನಾದ ಪರಮಪುರುಷ, ಹೃತ್ಕಮಲ ಮದ್ಯನಿವಾಸಿ ಭಗವಂತನ ಚಿಂತನೆ\nಮಾಡಬೇಕು ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಮಹತೋಮಹಿಯಾದ ಭಗವಂತ ನಿನ್ನ ಹೃದಯದಲ್ಲಿ ಅಹೋರಣೀಯವಾಗಿ\nಇರುವುದನ್ನು ಧ್ಯಾನದಲ್ಲಿ ಗುರುತಿಸು ಎನ್ನುವುದು ಇಲ್ಲಿ ಕೃಷ್ಣನ ಸಂದೇಶ. ಭಗವಂತ ಸರ್ವಗತ, ಸರ್ವಸಮರ್ಥ,\nಸರ್ವಗುಣಪೂರ್ಣ, ಅನಾಧಿನಿತ್ಯ. ಅಂತಹ ಭಗವಂತ ನಮ್ಮ ಹೃತ್ಕಮಲದಲ್ಲಿ ವಾಸಿಸಿದ್ದಾನೆ ಮತ್ತು\nದಿವ್ಯನಾಗಿದ್ದಾನೆ.\n\nಇಲ್ಲಿ ಬಳಸಿರುವ ದಿವ್ಯ ಪದಕ್ಕೆ ಅನೇಕ ಅರ್ಥಗಳಿವೆ. ಮೂಲವಾಗಿ ದಿವ್ಯ ಅಥವಾ 'ದೇವರು' ಈ ಪದಗಳು 'ದಿವು'\nಎನ್ನುವ ಧಾತುವಿನಿಂದ ಬಂದಿರುವುದು. ಪ್ರಾಚೀನ ಧಾತು ಪಾಠದಲ್ಲಿ ಈ ಧಾತುವಿಗೆ ಏಳು ಅರ್ಥವನ್ನು\nನೋಡಬಹುದು; ಅವುಗಳೆಂದರೆ: ೧) ಧ್ಯುತಿ ೨) ವಿಜಿಗೀಶ ೩) ಕಾಂತಿ ೪) ಸ್ತುತಿ ೫) ವ್ಯವಹಾರ ೬) ಕ್ರೀಡಾ ೭)\n\nಗತಿಶು. ಇತ್ತೀಚೆಗೆ ಮೋದ, ಮದ ಮತ್ತು ಸ್ವಪ್ನ ಎನ್ನುವ ಇನ್ನೂ ಮೂರು ಅರ್ಥವನ್ನು ಸೇರಿಸಿದ್ದಾರೆ. ಆದರೆ ಇದು\nಪ್ರಾಚೀನ ಧಾತುಪಾಠದಲ್ಲಿ ಇಲ್ಲ. ಈಗ ಸಂಕ್ಷಿಪ್ತವಾಗಿ ಮೇಲಿನ ಏಳು ಅರ್ಥಗಳನ್ನು ನೋಡೋಣ.\n\n೧) ಧ್ಯುತಿ : ಧ್ಯುತಿ ಅಂದರೆ ಬೆಳಕಿನ ಸ್ವರೂಪ. ಬೆಳಕಿನ ಪುಂಜವಾದ ಸೂರ್ಯ ಚಂದ್ರಾದಿಗಳಿಗೆ ಬೆಳಕನ್ನೀಯುವ\nಭಗವಂತ ನಮ್ಮೊಳಗೆ ಜ್ಞಾನದ ಬೆಳಕನ್ನು ತುಂಬುತ್ತಾನೆ.\n\n೨) ವಿಜಿಗೀಶ: ಭಗವಂತ ಎಲ್ಲರಿಗಿಂತ ಎತ್ತರದಲ್ಲಿರುವವನು ಹಾಗೂ ಗೆಲುವಿನ ಸ್ವರೂಪ.\n\n೩) ಕಾಂತಿ: ಕೇವಲ ಇಚ್ಚೆಯಿಂದ ಸೃಷ್ಟಿ ಮಾಡಬಲ್ಲವ. ನಮಗೆ ಇಚ್ಚೆ ಯನ್ನು ಕೊಟ್ಟವ ಹಾಗೂ ಅದನ್ನು ಅವರವರ\nಯೋಗ್ಯತೆಗೆ ತಕ್ಕಂತೆ ಪೂರೈಸುವವ.\n\n೪) ಸ್ತುತಿ: ಎಲ್ಲರಿಂದ ಸ್ತುತನಾದವನು; ಎಲ್ಲರೂ ಯಾರನ್ನು ಸ್ತುತಿಸುತ್ತಾರೋ ಅವನು ಸರ್ವಶಬ್ದ ವಾಚ್ಯನಾದ\nಭಗವಂತ.\n\n೫) ವ್ಯವಹಾರ: ಜಗತ್ತಿನ ಸಮಸ್ತ ವ್ಯವಹಾರವನ್ನು ನಿರ್ವಹಿಸುವವ.\n\n೬) ಕ್ರೀಡಾ: ಸೃಷ್ಟಿ-ಸ್ಥಿತಿ-ಸಂಹಾರ ಇದು ಭಗವಂತನಿಗೊಂದು ಕ್ರೀಡೆ. ಹುಟ್ಟು-ಸಾವು, ಸರ್ವ ವ್ಯವಹಾರಗಳು\nಆತನಿಗೊಂದು ಕ್ರೀಡೆ.\n\n೭) ಗತಿಶು: ಚಲನೆ ಮತ್ತು ಜ್ಞಾನ ಕೊಟ್ಟ ವ. ಯಾರು ಎಲ್ಲಾ ಕಡೆ ಗತನಾಗಿದ್ದಾನೋ; ಎಲ್ಲವನ್ನೂ ತಿಳಿದಿದ್ದಾನೋ;\nಎಲ್ಲರೊಳಗೆ ಬಿಂಬ ರೂಪದಲ್ಲಿ ನೆಲೆಸಿದ್ದಾನೋ ಅವನು ದಿವ್ಯ ಅಥವಾ 'ದೇವ'\n\nಹೀಗೆ ಅನೇಕ ಅರ್ಥಗಳನ್ನು 'ದಿವ್ಯ' ಎನ್ನುವ ಪದದಲ್ಲಿ ಕಂಡುಕೊಳ್ಳಬಹುದು. \"ಓ ದೇವರೇ” ಎನ್ನುವಾಗ ಮೇಲಿನ\nಅರ್ಥವನ್ನು ಒಮ್ಮೆ ನೆನೆದರೆ ಅದರಿಂದಾಗುವ ಆನಂದ ಅಪರಿಮಿತ. ಭಗವಂತನ ನಾಮದಲ್ಲಿ ಅಷ್ಟೊಂದು\nಬಲವಿದೆ. ನಾವು ಭಗವಂತನ ಜೊತೆಗೇ ಇದ್ದೂ ಕೂಡಾ ಮಾನಸಿಕವಾಗಿ ಆತನಿಂದ ದೂರವಿದ್ದೇವೆ. ಭಗವಂತನ\nನಿರಂತರ ಅನುಚಿಂತನೆಯಿಂದ ನಾವು ಆತನ ಸಾಕ್ಷಾತ್ಕಾರ ಪಡೆಯಬಹುದು.\n\nಈ ಅಧ್ಯಾಯದ ಮುಂದಿನ ಭಾಗದಲ್ಲಿ ಕೃಷ್ಣ ಭಗವಂತನನ್ನು ಅನುಚಿಂತನೆ ಮಾಡುವುದು ಅಂದರೆ ಏನು\nಎನ್ನುವುದನ್ನು ವಿವರಿಸುತ್ತಾನೆ. ಒಬ್ಬ ಧ್ಯಾನ ಮಾಡುವವ ಭಗವಂತನನ್ನು ಯಾವರೀತಿ ಧ್ಯಾನ ಮಾಡಬೇಕು\nಎನ್ನುವ ಚಿತ್ರಣವನ್ನು ಮುಂದಿನ ಶ್ಲೋಕಗಳಲ್ಲಿ ಕಾಣಬಹುದು.",
  "8.9": "ಕವಿಮ್‌ ಪುರಾಣಮ್‌ ಅನುಶಾಸಿತಾರಮ್‌ ಅಣೋಃ ಅಣೀಯಾಂಸಮ್‌ ಅನುಸ್ಮರೇತ್‌ ಯಃ ।\n\nಸರ್ವಸ್ಯ ಧಾತಾರಮ್‌ ಅಚಿಂತ್ಯ ರೂಪಮ್‌ ಆದಿತ್ಯ ವರ್ಣಮ್‌ ತಮಸಃ ಪರಸ್ತಾತ್‌ -ಎಲ್ಲವನ್ನು ಬಲ್ಲವನು,\nಎಲ್ಲಕ್ಕೆಂತ ಮೊದಲಿದ್ದವನು, ಎಲ್ಲರ ಒಡೆಯ, ಅಣುವಿಗಿಂತ ಅಣು, ಎಲ್ಲವನ್ನು ಹೊತ್ತು ಸಲಹುವವನು, ಬಗೆಗೆ\nನಿಲುಕದ ನಿಟ್ಟಿನವನು, ಸೂರ್ಯನಂತೆ ಬೆಳಗುವವನು, ಕತ್ತಲಿನಾಚೆಗಿರುವವನು[ಸಾವಿರದವನು]-ಹೀಗೆಂದು\nಅವನನ್ನು ಸ ,ಲಿಸುವವನು[ಅವನನ್ನೇ ಸೇರುತ್ತಾನೆ].\n\nನಮ್ಮ ಅಂತರ್ಯಾಮಿ ಭಗವಂತನನ್ನು ಧ್ಯಾನ ಮಾಡುವಾಗ “ಅನುಸಂಧಾನ ಮಾಡಬೇಕಾದ ವಿಷಯಗಳನ್ನು'\nಕೃಷ್ಣ ಇಲ್ಲಿ ಬಿಡಿಸಿ ಬಿಡಿಸಿ ಹೇಳುತ್ತಾನೆ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ಭಗವಂತನನ್ನು ಕವಿ ಎಂದು ಉಪಾಸನೆ ಮಾಡು”\nಎಂದು. ಇಲ್ಲಿ ಕವಿ ಎಂದರೆ ಸರ್ವಜ್ಞ ಎಂದರ್ಥ. ನಮಗೆ ಮೊದಲು ಬೇಕಾಗಿರುವುದು ಜ್ಞಾನ. ಜ್ಞಾನವಿಲ್ಲದೆ\nಆನಂದವಿಲ್ಲ. ಇದಕ್ಕಾಗಿ ಭಗವಂತನಲ್ಲಿ ಮೊದಲು ಅರಿವನ್ನು ಬೇಡಬೇಕು. ಎರಡನೇಯದಾಗಿ ಭಗವಂತನನ್ನು\nಪುರಾಣಮ್‌ ಎಂದು ಉಪಾಸನೆ ಮಾಡು ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಪುರಾಣ ಎಂದರೆ ಎಲ್ಲಕ್ಕಿಂತ ಮೊದಲಿದ್ದವ ಮತ್ತು\nಸರ್ವ ಕಾಲದಲ್ಲೂ ಏಕಪ್ರಕಾರನಾಗಿರುವವ. ನಮ್ಮ ಪುರ(ದೇಹ)ದೊಳಗೆ ಕೂತು ಪ್ರತೀಕ್ಷಣದಲ್ಲಿಯೂ ನಮ್ಮನ್ನು\nನಿಯಂತ್ರಿಸುವವ ಎನ್ನುವ ಅನುಸಂಧಾನ.\n\nಮೂರನೆಯದಾಗಿ ಭಗವಂತ 'ಅನುಶಾಸಿತಾರಮ್‌'. ಅಂದರೆ ಪ್ರತಿಯೊಂದನ್ನೂ ಕೂಡಾ ನಿಯಮನ(ಶಾಸನ)\nಮಾಡುವವನು. ನನ್ನ ಇರವು, ಜಗತ್ತಿನ ಪ್ರತಿಯೊಂದು ವಸ್ತುವಿನ ಇರವು-ಅವನ ನಿಯಂತ್ರಣಕ್ಕೊಳಪಟ್ಟಿದೆ;\nಭಗವಂತ ಪ್ರತಿಯೊಂದು ಜೀವ ಸ್ವರೂಪದ ಯೋಗ್ಯತೆಗನುಗುಣವಾಗಿ ಶಾಸನ ಮಾಡುತ್ತಾನೆ-ಎಂದು ಅರಿತು\nಅವನನ್ನು ಅನುಸಂಧಾನ ಮಾಡಬೇಕು. ಸಮಸ್ತ ಬ್ರಹ್ಮಾಂಡದಲ್ಲಿ ತುಂಬಿದ ಆ ಭಗವಂತನೇ ಅಣುವಿಗಿಂತ\nಅಣುವಾಗಿ ಜೀವ ಸ್ವರೂಪದ ಒಳಗೂ ತುಂಬಿದ್ದಾನೆ. “ಎಲ್ಲವನ್ನೂ ಧರಿಸಿದ ಭಗವಂತನೇ ನಮ್ಮೊಳಗೆ ಕೂತು\nಪೋಷಣೆ ಮಾಡುತ್ತಿದ್ದಾನೆ. ಆತ ಇಡೀ ವಿಶ್ವದ ಧಾರಣೆ-ಪೋಷಣೆ ಮಾಡುವ ಶಕ್ತಿ. ಆತ ಸರ್ವರಿಗೂ\nಸರ್ವಾಭೀಷ್ಟವನ್ನು ಕೊಡುವವ” ಎಂದು ಅವನನ್ನು ಧ್ಯಾನ ಮಾಡಬೇಕು.\n\nಭಗವಂತ ನಮ್ಮ ಕಲ್ಪನೆಗೆ ಎಟುಕದ ವಸ್ತು ಎಂದು ನಾವು ತಿಳಿದಿರಬೇಕು. ಆತನದು ನಮ್ಮ ಮಾತು ಮನಸ್ಸಿಗೆ\nಮುಟ್ಟದ ರೂಪ. ಧ್ಯಾನದಲ್ಲಿ ಜೀವಸ್ವರೂಪದ ಕಣ್ಣಿನಿಂದ ಭಗವಂತನನ್ನು ನೋಡಿದರೆ ಆತ ಉದಿಸುವ\nಸೂರ್ಯನಂತೆ ಕಾಣುತ್ತಾನೆ. ಆತನ ಬಣ್ಣ ಪ್ರಕೃತಿ ನಿರ್ಮಿತವಾದ ಬಣ್ಣವಲ್ಲ, ಅದು ತ್ರಿಗುಣಾತೀತವಾದ ಎಂದೂ\nಅಳಿವಿರದ ಅಪ್ರಾಕೃತ ಬಣ್ಣ. ಹೀಗೆ ಭಗವಂತನನ್ನು ತಿಳಿದು ನಿರಂತರ ಚಿಂತನೆ ಮಾಡುವವ ತನ್ನ ದೇಹ ತ್ಯಾಗ\nಮಾಡುವಾಗ ಭಗವಂತನನ್ನೇ ನೆನೆದು ಭಗವಂತನನ್ನು ಸೇರುತ್ತಾನೆ.\n",
  "8.10": "ಪ್ರಯಾಣ ಕಾಲೇ ಮನಸಾ ಅಚಲೇನ ಭಕ್ತ್ಯಾ ಯುಕ್ತಃ ಯೋಗಬಲೇನ ಚ ಏವ |\n\nಭ್ರುವೋಃ ಮಧ್ಯೇ ಪ್ರಾಣಮ್‌ ಆವೇಶ್ಯ ಸಮ್ಯಕ್‌ ಸಃ ತಮ್‌ ಪರಮ್‌ ಪುರುಷಮ್‌ ಉಪೈತಿ ದಿವ್ಯಮ್‌ -ಕೊನೆಯ\nಕಾಲದಲ್ಲಿ ಭಗವಂತನಲ್ಲಿ ಭಕ್ತಿಯಿಟ್ಟು, ಬಿಗಿಯಾದ ಬಗೆಯಿಂದ , ಹುಬ್ಬುಗಳ ನಡುವೆ ಪ್ರಾಣವಾಯುವನ್ನು\nಕದಲದಂತೆ ಇರಗೊಳಿಸಿ, ಪ್ರಾಹಾಯಾಮದ ಯೋಗದ ಮೂಲಕ ಕೂಡಾ ಲೀಲಾಲೋಲನಾದ ಆ\nಪರಮಪುರುಷನನ್ನು ಪಡೆಯಬಹುದು.\n\nಭಗವಂತನನ್ನು ಸೇರುವ ಇನ್ನೊಂದು ಮಾರ್ಗ ಹಠಯೋಗ. ಈ ಮಾರ್ಗ ಕರಠಿಣವಾದದ್ದು. ಇದು\nಯಮನಿಯಮನ-ಪ್ರಾಹಾಯಾಮ-ಪ್ರತ್ಯಾಹಾರಗಳಿಂದ ಭಗವಂತನನ್ನು ಸೇರುವ ಬಗೆ. ಈ ಮಾರ್ಗದಲ್ಲಿ\n\nಸಾಧನೆ ಮಾಡುವವರು ತಮ್ಮ ಸಾವಿನ ಕಾಲದಲ್ಲಿ ಏನು ಮಾಡಬೇಕು ಎನ್ನುವುದನ್ನು ಕೃಷ್ಣ ಈ ಶ್ಲೋಕದಲ್ಲಿ\nವಿವರಿಸುತ್ತಾನೆ. ಆಸನ ಪ್ರಾಣಾಯಾಮ ಮಾಡಿ ಸ್ಥಿರವಾದ ದೇಹ, ಸ್ಥಿರವಾದ ಪ್ರಾಣಮಯ ಕೋಶವನ್ನು\nಸಾಧಿಸಿದ ಮೇಲೆ, ಪ್ರತ್ಯಾಹಾರದ ಮೂಲಕ ತನ್ನೊಳಗೆ ತುಂಬಿದ ಕೆಟ್ಟ ಸಂಗತಿಗಳನ್ನು ಹೊರ ಹಾಕಿ, ಕೆಟ್ಟ\nವಿಚಾರ ಒಳಬಾರದಂತೆ ತಡೆದು, ಏಕಾಗ್ರತೆ ಸಾಧಿಸುವುದು. ಇದು ತುಂಬಾ ಧೀರ್ಥವಾದ ಕಠಿಣ ಸಾಧನೆ.\nಇಂತವರು ತಮ್ಮ ಹೃತ್ಕಮಲ ಮಧ್ಯ(ಅನಾಹತ ಚಕ್ರ) ದಲ್ಲಿ ಪ್ರಾಣಶಕ್ತಿಯೊಂದಿಗಿರುವ ಜೀವವನ್ನು ಅಲ್ಲಿಂದ\nಊರ್ಧ್ವ ಮುಖವಾಗಿ ವಿಶುದ್ಧಿಚಕ್ರದ ಮೂಲಕ ಭ್ರುಮಧ್ಯ (ಎರಡು ಹುಬ್ಬುಗಳ ನಡುವೆ ಇರುವ ಆಜ್ಞಾ ಚಕ್ರ)\nತಂದು ನಿಲ್ಲಿಸಬೇಕು. ಈ ಪ್ರಕ್ರಿಯೆ ಅತ್ಯಂತ ಕಠಿಣ. ಈ ಸಂಪೂರ್ಣ ಕ್ರಿಯೆಯಲ್ಲಿ ಅನನ್ಯ ಭಕ್ತಿ ಬಹಳ ಮುಖ್ಯ. ಈ\nರೀತಿ ಭ್ರುಮಧ್ಯದಿಂದ ಸಹಸ್ರಾರದ ಬ್ರಹ್ಮರಂದ್ರದ ಮೂಲಕ ಜೀವ ಹೊರ ಹೋದರೆ ಅವರು ನೇರವಾಗಿ\nಭಗವಂತನನ್ನು ಸೇರುತ್ತಾರೆ.\n\nಈ ರೀತಿಯ ಹಠಯೋಗ ಕಠಿಣ ಸಾಧನವಾಗಿರುವುದರಿಂದ ಪ್ರಾಚೀನರು ಅದಕ್ಕೆ ಪೂರಕವಾದ ಅತ್ಯಂತ ಸರಳ\nವಿಧಾನವನ್ನು ತಮ್ಮ ದೈನಂದಿನ ಜೀವನದಲ್ಲಿ ತೊಡಗಿಸಿಕೊಂಡಿದ್ದರು. ಇದಕ್ಕೆ ಉತ್ತಮ ಉದಾಹರಣೆ\nಊರ್ಧ್ವಪುಂಡ್ರ. ಇದು ಜೀವದ ಊರ್ಧ್ವಮುಖ ಗತಿಗೆ ಸಂಬಂಧಪಟ್ಟದ್ದು. ಇದು ಪೂರ್ಣ ಪ್ರಮಾಣದಲ್ಲಿ\nದೇಹದಲ್ಲಿರುವ ಶಕ್ತಿ ಕೇಂದ್ರಗಳನ್ನು ಜಾಗೃತಿಗೊಳಿಸುವ ಒಂದು ಸರಳ ವಿಧಾನ. [ಆದರೆ ಇಂದು ಸಾವು ಏಕೆ\nನಾಮ ಹಾಕಿ ಕೊಳ್ಳುತ್ತೇವೆ ಎನ್ನು ವುದೇ ನಮಗೆ ತಿಳಿದಿಲ್ಲ].\n\nಹಠಯೋಗವನ್ನು ಸರಿಯಾದ ಮಾರ್ಗದರ್ಶನ ಇಲ್ಲದೆ ಮಾಡುವುದು ಅಪಾಯಕಾರಿ. ಭಾಗವತದ ದ್ವಿತೀಯ\nಸ್ಕಂದದಲ್ಲಿ ಜೀವವನ್ನು ಮೇಲಕ್ಕೆ ಕೊಂಡೊಯ್ಯುವ ಹಂತವನ್ನು ಒಂದು ಅಧ್ಯಾಯದಲ್ಲಿ ವಿವರವಾಗಿ\nವಿವರಿಸಿದ್ದಾರೆ. ಹೀಗೆ ಯೋಗದ ಮೂಲಕ ಹಠಮಾಡಿ ಭಗವಂತನನ್ನು ಸೇರಬಹುದು, ಅಥವಾ ತಾಯಿಯಲ್ಲಿ\nಮಗು ಹಠಮಾಡಿದಂತೆ ಭಗವಂತನಲ್ಲಿ ಭಕ್ತ ಸದಾ ಭಕ್ತಿಯೆಂಬ ಹಠಮಾಡಿ ಆತನನ್ನು ಸೇರಬಹುದು.\n\nಹೀಗೆ ಭ್ರುಮಧ್ಯದಲ್ಲಿ ಜೀವವನ್ನು ತಂದು ನಿಲ್ಲಿಸುವ ವಿಧಾನವನ್ನು ವಿವರಿಸಿದ ಕೃಷ್ಣ, ಅಲ್ಲಿಂದ ಮುಂದೆ\nಸಹಸ್ರಾರದ ಶಕ್ತಿ ಕೇಂದ್ರದ ದ್ವಾರದ ಮೂಲಕ ಜೀವ ಹೊರ ಹೋಗುವ ವಿಧಾನವನ್ನು ಇನ್ನೂ ವಿವರವಾಗಿ\nಮುಂದಿನ ಮೂರು ಶ್ಲೋಕದಲ್ಲಿ ವಿವರಿಸುತ್ತಾನೆ.\n",
  "8.11": "ಯತ್‌ ಅಕ್ಷರಂ ವೇದವಿದಃ ವದಂತಿ ವಿಶಂತಿ ಯತ್‌ ಯತಯಃ ವೀತ ರಾಗಾಃ |\n\nಯತ್‌ ಇಚ್ಛಂತಃ ಬ್ರಹ್ಮಚರ್ಯಮ್‌ ಚರಂತಿ ತತ್‌ ತೇ ಪದಮ್‌ ಸಂಗ್ರಹೇಣ ಪ್ರವಕ್ಷ್ಯೇ -ವೇದ ಬಲ್ಲವರು\nಅಳಿವಿರದ ಅದನ್ನು 'ಅಕ್ಷರ' ಎನ್ನು ತ್ತಾರೆ. ಭೋಗದ ಒಲವು ತೊರೆದ ಸಾಧಕರು ಅದನ್ನೇ ಸೇರುತ್ತಾರೆ. ಅದನ್ನು\nಸೇರಬಯಸಿಯೇ ಬಗೆಯಲ್ಲಿ ಆ ಹಿರಿಯ ತತ್ವವನ್ನು ಚಿಂತಿಸುತ್ತಾರೆ. ಅಂತಹ ಮುಕ್ತಿಪ್ರದವಾದ\nಪರತತ್ವವನ್ನುನಿನಗೆ ಅಡಕವಾಗಿ ಹೇಳುತ್ತೇನೆ.\n\nಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ಯೋಗ ಸಾಧನೆಯಿಂದ ಭ್ರುಮಧ್ಯೆ ತಂದು ನಿಲ್ಲಿಸಿದ ಜೀವವನ್ನು ಅಲ್ಲಿಂದ ಧ್ಯಾನ ಮಾಡುತ್ತಾ\nಮೇಲಕ್ಕೆ ಸಹಸ್ರಾರದತ್ತ ತೆಗೆದುಕೊಂಡು ಹೋಗಬೇಕು” ಎಂದು. ಈ ಕಾಲದಲ್ಲಿ ಧ್ಯಾನ ಮಾಡಬೇಕಾದ ರೂಪದ\nಬಗ್ಗೆ ಹೇಳುತ್ತಾ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ವೇದವನ್ನು ಬಲ್ಲವರು ಅದನ್ನು ಅಳಿವಿರದ 'ಅಕ್ಷರ'(ಓಂಕಾರ ಎನ್ನುವ\nಅಕ್ಷರದಿಂದ ಪ್ರತಿಪಾಧ್ಯನಾದ ಸರ್ವಶಬ್ದ ವಾಚ್ಯ) ಎನ್ನುತ್ತಾರೆ” ಎಂದು. ಮಹಾ ಪ್ರಯತ್ನದಿಂದ ಭಗವಂತನನ್ನು\nಒಲಿಸಿಕೊಂಡವರು, ಪ್ರಾಪಂಚಿಕ ಸೆಳೆತದಿಂದ ಪಾರಾದವರು, ಆ ಭಗವಂತನನ್ನು ಹೋಗಿ ಸೇರುತ್ತಾರೆ. “ಅವರು\nಅಂತಹ ಭಗವಂತನನ್ನು ತಿಳಿದುಕೊಳ್ಳಬಯಸಿ ಬ್ರಹ್ಮಚರ್ಯವನ್ನು ಜೀವನದಲ್ಲಿ ಅಳವಡಿಸಿಕೊಳ್ಳುತ್ತಾರೆ”\nಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. [ಇಲ್ಲಿ 'ಬ್ರಹ್ಮಚರ್ಯ' ಎಂದರೆ ನಿಘಂಟಿನಲ್ಲಿ ಹೇಳುವ ದೈಹಿಕ ಬ್ರಹ್ಮಚರ್ಯವಲ್ಲ, ಬದಲಿಗೆ\n\"ಬ್ರಹ್ಮಣಿ ಚರಣಂ'-ಭಗವಂತನಲ್ಲಿ ಮನಸ್ಸು ನೆಲೆಗೊಳ್ಳುವಿಕೆ.ಬ್ರಹ್ಮಚರ್ಯ]. “ಅದನ್ನು ಸೇರಬಯಸಿಯೆ\nಬಗೆಯಲ್ಲಿ ಆ ಹಿರಿಯ ತತ್ವವನ್ನು ಚಿಂತಿಸುತ್ತಾರೆ. ಈ ರೀತಿ ಮೋಕ್ಷವನ್ನು ಪಡೆಯುವ ಪ್ರಕ್ರಿಯೆಯನ್ನು\nಸಂಗ್ರಹವಾಗಿ ನಿನಗೆ ಹೇಳುತ್ತೇನೆ” ಎಂದು ಹೇಳಿ ಕೃಷ್ಣ ಈ ಪ್ರಕ್ರಿಯೆಯನ್ನು ಮುಂದಿನ ಶ್ಲೋಕಗಳಲ್ಲಿ\nಅರ್ಜುನನಿಗೆ ವಿವರಿಸುತ್ತಾನೆ.",
  "8.12": "ಓಮಿತ್ಯೇಕಾಕ್ಷರಂ ಬ್ರಹ್ಮ ವ್ಯಾಹರನ್‌ ಮಾಮ",
  "8.13": "ಸರ್ವದ್ವಾರಾಣಿ ಸಂಯಮ್ಯ ಮನಃ ಹೃದಿ ನಿರುದ್ಧ ಚ।\n\nಮೂರ್ಧ್ನಿ ಆಧಾಯಾ ಆತ್ಮನಃ ಪ್ರಾಣಮ್‌ ಆಸ್ಥಿತಃ ಯೋಗ ಧಾರಹಣಾಮ್‌ |\n\nಓಂ ಇತಿ ಏಕಾಕ್ಷರಮ್‌ ಬ್ರಹ್ಮ ವ್ಯಾಹರನ್‌ ಮಾಮ್‌ ಅನುಸ್ಮರನ್‌ ।\n\nಯಃ ಪ್ರಯಾತಿ ತ್ಯಜನ್‌ ದೇಹಮ್‌ ಸಃ ಯಾತಿ ಪರಮಾಮ್‌ ಗತಿಮ್‌ - ಎಲ್ಲಾ ನಾಡಿ ದ್ವಾರಗಳನ್ನು ತಡೆ\nಹಿಡಿದು , ಬಗೆಯನ್ನು ಭಗವಂತನಲ್ಲೇ ಬಿಗಿ ಹಿಡಿದು, ತನ್ನ ಪ್ರಾಣವಾಯುವನ್ನು ನೆತ್ತಿಯಲ್ಲಿರಿಸಿ ಯೋಗ\nಸಾಧನೆಯಲ್ಲಿ ನೆಲೆಗೊಂಡವನು, 'ಓಂ' ಎಂಬ ಒಂದಕ್ಷರದಿಂದ ವಾಚ್ಯನಾದ ಪರತತ್ವವನ್ನು ಕೊಂಡಾಡುತ್ತಾ,\nನನ್ನನ್ನು ನೆನೆಯುತ್ತಾ, ದೇಹ ತೊರೆದು ಮೇಲೇರಿದವನು ಮರಳಿ ಬರದ ತಾಣವನ್ನು ಸೇರುತ್ತಾನೆ.\n\nಸಹಸ್ರಾರದತ್ತ ಜೀವವನ್ನು ಕೊಂಡೊಯ್ಯುವಾಗ ದೇಹದ ಇತರ ಎಲ್ಲಾ ದ್ವಾರಗಳನ್ನೂ ಯೋಗ ಬಲದಿಂದ\nಮುಚ್ಚಬೇಕು ಮತ್ತು ಮುಚ್ಚಿರುವ ಸಹಸ್ರಾರದ ಬಾಗಿಲನ್ನು ತೆರೆದು ಹೊರಹೋಗಬೇಕು. ಈ ರೀತಿ ಮಾಡುವಾಗ\nಮನಸ್ಸನ್ನು ಆ ಸರ್ವಸಂಹಾರಕ ಭಗವಂತನಲ್ಲಿ ನೆಲೆಗೊಳಿಸಬೇಕು. ಪೂರ್ಣಪ್ರಮಾಣದಲ್ಲಿ ತನ್ನ\nಯೋಗಾಭ್ಯಾಸವನ್ನು ಬಳಸಿ, ಶ್ವಾಸ ನಿರೋಧ ಮಾಡಿ, ಮನಸ್ಸನ್ನು ಭಗವಂತನಲ್ಲಿಟ್ಟು ಧ್ಯಾನ ಮಾಡಬೇಕು.\n\n“ಓಂಕಾರ ಪ್ರತಿಪಾಧ್ಯನಾದ ನನ್ನನ್ನು ಓಂಕಾರದಿಂದ ನೆನೆಯುತ್ತಾ ಸಹಸ್ರರದ ಬಾಗಿಲಿನಿಂದ ಹೊರಬಂದು\nದೇಹ ತ್ಯಾಗ ಮಾಡಿ ಮೇಲೇರಿದವನು ಮುಂದೆಂದೂ ಮರಳಿ ಬರದ ತಾಣವಾದ ಮೋಕ್ಷ(ಭಗವಂತ)ವನ್ನು\n\nಸೇರುತ್ತಾನೆ\".\n\nಈ ಸಾಧನೆ ಕೇವಲ ಹಠಯೋಗಿಗಳಿಗೆ ಸಾಧ್ಯ ಮತ್ತು ಇದು ತುಂಬಾ ಕಷ್ಟದ ಸಾಧನೆ. ಎಲ್ಲರೂ ಈ ರೀತಿ\nಯೋಗಾಭ್ಯಾಸ ಮಾಡಿ ಸಿದ್ಧಿ ಪಡೆಯುವುದು ಸಾಧ್ಯವಿಲ್ಲ. ಅದಕ್ಕಾಗಿ ಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ಕೃಷ್ಣ ಸುಲಭದ\nಮಾರ್ಗವನ್ನು ವಿವರಿಸುತ್ತಾನೆ.\n",
  "8.14": "ಅನನ್ಯ ಚೇತಾಃ ಸತತಮ್‌ ಯಃ ಮಾಮ್‌ ಸ್ಮರತಿ ನಿತ್ಯಶಃ ।\nತಸ್ಯ ಅಹಮ್‌ ಸುಲಭಃ ಪಾರ್ಥ ನಿತ್ಯ ಯುಕ್ತಸ್ಯ ಯೋಗಿನಃ -ಪಾರ್ಥಾ, ಬೇರೇನನ್ನೂ ನೆನೆಯದೆ ಅನುದಿನವೂ\nನಿರಂತರ ನನ್ನನ್ನು ನೆನೆಯುವವನಿಗೆ, ಅಂತಹ ನಿರಂತರ ಸಾಧನೆಯಿಂದ ಸಿದ್ಧಿಪಡೆದವನಿಗೆ ನಾನು ಕೈಸೆರೆ.\n\n“ನಿರಂತರ ನಿತ್ಯ ಭಗವಂತನ ಚಿಂತನೆ ಮಾಡುತ್ತಾ ಬೇರೇನನ್ನೂ ನೆನೆಯದೇ ನನ್ನ ನ್ನು ಭಜಿಸುವ ಸಾಧಕನಿಗೆ\nನಾನು ಅನಾಯಾಸವಾಗಿ ಸ್ವಾಧೀನನಾಗುತ್ತೇನೆ” ಎನ್ನು ತ್ತಾನೆ ಕೃಷ್ಣ. ಸಾಧನೆಯಲ್ಲಿ ನಿತ್ಯ ತೊಡಗಿ, ಸಾಧನೆಯ\nತುದಿ ಮುಟ್ಟಿದವ ಬೇರೆ ಯಾವ ಪ್ರಯತ್ನ ವೂ ಇಲ್ಲದೆ ಭಗವಂತನನ್ನು ಸೇರುತ್ತಾನೆ\n",
  "8.15": "ಮಾಮ್‌ ಉಪೇತ್ಯ ಪುನಃ ಜನ ದುಃಖ ಆಲಯಮ್‌ ಅಶಾಶ್ವತಮ್‌ |\n\nನ ಅಪ್ಪುವಂತಿ ಮಹಾ ಆತ್ಮಾನಃ ಸಂಸಿದ್ದಿಮ್‌ ಪರಮಾಮ್‌ ಗತಾಃ -ಹಿರಿಯ ಸಿದ್ಧಿಯನ್ನು ಪಡೆದ ಇಂತಹ\nಜೀವಗಳು ನನ್ನನ್ನು ಪಡೆದ ಮೇಲೆ ದುಗುಡಗಳ ನೆಲೆಯಾದ ನಾಲ್ಕು ದಿನದ ಈ ಸಂಸಾರದಲ್ಲಿ ಮರಳಿ ಹುಟ್ಟಿ\nಬರುವುದಿಲ್ಲ.\n\nಸಾಧನೆಯ ಮೂಲಕ ಸಿದ್ಧಿಯನ್ನು ಪಡೆದು ಭಗವಂತನನ್ನು ಸೇರಿದ ಜೀವರು ಎಂದೂ ದುಃಖಮಾಯವಾದ ಮತ್ತು\nಅಶಾಶ್ವತವಾದ ಈ ಸಂಸಾರದಲ್ಲಿ ಮರಳಿ ಹುಟ್ಟುವುದಿಲ್ಲ. “ನನ್ನನ್ನು ಬಂದು ಸೇರುವವರು ಪುಣ್ಯಾತ್ಮರು.\nಜಗತ್ತಿನಲ್ಲಿ, ಜೀವನದ ಸಾಧನೆಯಲ್ಲಿ ಅತ್ಯಂತ ಶ್ರೇಷ್ಠವಾದ ಸಿದ್ಧಿ ಎಂದರೆ ಭಗವಂತನ ಸಾಕ್ಷಾತ್ಕಾರ. ಅದನ್ನು\nಪಡೆದವರು ಮತ್ತೆ ಸಂಸಾರದ ಬಂಧದಲ್ಲಿ ಸಿಲುಕಿ ಒದ್ದಾಡುವ ಅಗತ್ಯವಿಲ್ಲ” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.",
  "8.16": "ಆ ಬ್ರಹ್ಮಭುವನಾತ್‌ ಲೋಕಾಃ ಪುನಃ ಆವರ್ತಿನಃ ಅರ್ಜುನ ।\nಮಾಮ್‌ ಉಪೇತ್ಯ ತು ಕೌಂತೇಯ ಪುನಃ ಜನ್ಮ ನ ವಿದ್ಯತೇ -ಅರ್ಜುನಾ, ಬ್ರಹ್ಮ ಲೋಕದ ತನಕದ ಎಲ್ಲಾ\nಲೋಕಗಳಿಂದಲೂ ಮರಳಿ ಬರಲೇಬೇಕು. ಕೌಂತೇಯಾ, ನನ್ನ ನ್ನು ಪಡೆದಾಗ ಮಾತ್ರ ಮರುಹುಟ್ಟು ಇಲ್ಲ.\n\nಬ್ರಹ್ಮ ಲೋಕದಿಂದ ಹಿಡಿದು ಇತರ ಎಲ್ಲಾ ಲೋಕಗಳಿಗೂ ಒಂದು ದಿನ ನಾಶವಿದೆ. ಚತುರ್ಮುಖ ಬ್ರಹ್ಮನ\nಆಯುಸ್ಸು 31,104,000,0000000(ಮೂವತ್ತೊಂದು ಸಾವಿರದ ನೂರಾ ನಾಲ್ಕು ಸಾವಿರ ಕೋಟಿ) ವರ್ಷ. ಇದು\nಭಗವಂತನಿಗೆ ಒಂದು ಹಗಲಿನಂತೆ! ಭಗವಂತ ಕಾಲಾತೀತ. ಆದ್ದರಿಂದ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ನನ್ನನ್ನು ಪಡೆದಾಗ\nಮಾತ್ರ ಮರುಹುಟ್ಟು ಇಲ್ಲ” ಎಂದು.\n",
  "8.17": "ಸಹಸ್ರ ಯುಗ ಪರ್ಯಂತಮ್‌ ಅಹಃ ಯತ್‌ ಬ್ರಹ್ಮಣಃ ವಿದುಃ ।\n\nರಾತ್ರಿಮ್‌ ಯುಗ ಸಹಸ್ರಾಂತಾಮ್‌ ತೇ ಅಹಃ ರಾತ್ರ ವಿದಃ ಜನಾಃ - ಸಾವಿರಾರು ಯುಗಗಳ ತನಕ\nಭಗವಂತನ ಹಗಲು ಮತ್ತು ಸಾವಿರಾರು ಯುಗಗಳ ತನಕ ಇರುಳು ಎಂದು ತಿಳಿಯುತ್ತಾರೆ, ಅವರು ಹಗಲು-\nಇರುಳು ಬಲ್ಲ ಜನರು.\n\nಭಗವಂತ ಕಾಲಾತೀತ ಆದರೂ ಕೂಡಾ ಆತನ ಅನುಸಂಧಾನಕ್ಕಾಗಿ ಆತನ ಸೃಷ್ಟಿ ಕಾಲವನ್ನು ಭಗವಂತನ\nಹಗಲೆಂದೂ ಮತ್ತು ಪ್ರಳಯ ಕಾಲವನ್ನು ಭಗವಂತನ ರಾತ್ರಿ ಎಂದೂ ಕರೆಯುತ್ತಾರೆ. ಒಂದು ಸಾವಿರ\nಯುಗಚಕ್ರದ ಆವೃತ್ತಿಗೆ ಒಂದು ಬ್ರಹ್ಮನ ದಿನ... ಯುಗಚಕ್ರ ಎಂದರೆ ಚತುರ್ಯುಗ- ಕಲಿಯುಗ 4,32,000\nವರ್ಷಗಳು; ದ್ವಾಪರ ಯುಗ 8,64,000 ವರ್ಷಗಳು; ತ್ರೇತಾಯುಗ 12,96,000 ವರ್ಷಗಳು; ಕೃತಯುಗ\n17,28,000 ವರ್ಷಗಳು; ಒಟ್ಟಿಗೆ ಒಂದು ಯುಗಚಕ್ರ ಎಂದರೆ 43,20,000 ವರ್ಷಗಳು. ಇಂತಹ ಒಂದು ಸಾವಿರ\nಯುಗ ಚಕ್ರಗಳು ಬ್ರಹ್ಮನ ಒಂದು ಹಗಲು. ಅಂದರೆ 432 ಕೋಟಿ ವರ್ಷ. ಆದ್ದರಿಂದ ಬ್ರಹ್ಮನ ಒಂದು ದಿನ ಅಂದರೆ\n864 ಕೋಟಿ ವರ್ಷ. ಚತುರ್ಮುಖ ಬ್ರಹ್ಮನ ಆಯುಸ್ಸು ಅಥವಾ ಸತ್ಯಲೋಕದ ಆಯುಸ್ಸು 100 ವರ್ಷ. ಅಂದರೆ\n864 ಕೋಟಿ × 360 × 100 = 31,104,000,0000000(ಮೂವತ್ತೊಂದು ಸಾವಿರದ ನೂರಾ ನಾಲ್ಕು ಸಾವಿರ\nಕೋಟಿ) ವರ್ಷ. ಇದು ಭಗವಂತನ ಸೃಷ್ಟಿ ಕಾಲ(ಹಗಲು). ನಂತರ ಮಹಾಪ್ರಳಯ. ಈ ಮಹಾಪ್ರಳಯದ ಕಾಲ\n31,104 ಸಾವಿರ ಕೋಟಿ ವರ್ಷಂ(ರಾತ್ರಿ). ಇದು ಭಗವಂತನ ಸೃಷ್ಟಿ ಮತ್ತು ಸಂಹಾರದ ಲೆಕ್ಕಾಚಾರ.\n\nಪ್ರಳಯಗಳಲ್ಲಿ ಮೂರು ವಿಧ. ೧. ಮನ್ವಂತರ ಪ್ರಳಯ; ೨. ದಿನಪ್ರಳಯ; ೩. ಮಹಾಪ್ರಳಯ. [ಈ ಮೂರು\nಪ್ರಳಯಗಳಲ್ಲದೆ ಇನ್ನೂ ಅನೇಕ ಚಿಕ್ಕ ಪ್ರಳಯಗಳಾಗುತ್ತವೆ. ಆ ಪ್ರಳಯಗಳಲ್ಲಿ ಭೂಮಿಯ ಯಾವುದೋ ಒಂದು\nಭಾಗ ನಾಶವಾಗಬಹುದು]. ಮನ್ವಂತರ ಪ್ರಳಯದಲ್ಲಿ ಭೂಮಿ ಪೂರ್ಣವಾಗಿ ನಾಶವಾಗುವುದಿಲ್ಲ-ಆದರೆ\nನಾಗರೀಕತೆ ನಾಶವಾಗುತ್ತದೆ. ದಿನಪ್ರಳಯ ಚತುರ್ಮುಖ ಬ್ರಹ್ಮನ ರಾತ್ರಿ. ಅಂದರೆ ಪ್ರತೀ 432 ಕೋಟಿ\nವರ್ಷಕ್ಕೊಮ್ಮೆ ದಿನಪ್ರಳಯ. ಈ ಪ್ರಳಯದಲ್ಲಿ ಭೂಮಿ ಪೂರ್ಣವಾಗಿ ನಾಶವಾಗುತ್ತದೆ. ಮಹಾಪ್ರಳಯ ಪ್ರತೀ\n31,104 ಸಾವಿರ ಕೋಟಿ ವರ್ಷಕ್ಕೊಮ್ಮೆ ಹಾಗೂ ಈ ಪ್ರಳಯದಲ್ಲಿ ಸತ್ಯ ಲೋಕದಿಂದ ಹಿಡಿದು ಸರ್ವ\nಲೋಕಗಳೂ ಸೂಕ್ಷಾತಿ ಸೂಕ್ಷ್ಮ ಪರಮಾಣುವಿನ ರೂಪದಲ್ಲಿ ಭಗವಂತನಲ್ಲಿ ಲೀನವಾಗುತ್ತವೆ.\n",
  "8.18": "ಅವ್ಯಕ್ತಾತ್‌ ವ್ಯಕ್ತಯಃ ಸರ್ವಾಃ ಪ್ರಭವಂತಿ ಅಹಃ ಆಗಮೇ |\nರಾತ್ರಿ ಆಗಮೇ ಪ್ರಲೀಯಂತೇ ತತ್ರ ಏವ ಅವ್ಯಕ್ತ ಸಂಜ್ಞಕೇ -ಕಾಣದ ಭಗವಂತನಿಂದ ಕಾಣುವ ಎಲ್ಲವೂ\nಹಗಲಾದಾಗ ರೂಪುಗೊಳ್ಳುತ್ತವೆ, ಇರುಳಾದಾಗ ಅದೇ ಕಾಣದ ಭಗವಂತನಲ್ಲಿ ಕಣ್ಮರೆಯಾಗುತ್ತವೆ.\n\nಮಹಾಪ್ರಳಯ ಕಾಲದಲ್ಲಿ ಅವ್ಯಕ್ತನಾದ ಭಗವಂತನಲ್ಲಿ ವ್ಯಕ್ತವಾಗಿರುವ ಈ ಪ್ರಪಂಚ ಪರಮಾಣುವಿನ ರೂಪದಲ್ಲಿ\nಸೇರಿಕೊಳ್ಳುತ್ತದೆ. ಪುನಃ ಸೃಷ್ಟಿ ಕಾಲದಲ್ಲಿ ಮರಳಿ ಸೂಕ್ಷ್ಮ ರೂಪದಿಂದ ಸ್ಥೂಲ ರೂಪವನ್ನು ಪಡೆದು\nವ್ಯಕ್ತವಾಗುತ್ತವೆ.\n",
  "8.19": "ಭೂತ ಗ್ರಾಮಃ ಸಃ ಏವ ಅಯಮ್‌ ಭೂತ್ವಾಭೂತ್ವಾ ಪ್ರಲೀಯತೇ |\nರಾತ್ರಿ ಆಗಮೇ ಅವಶಃ ಪಾರ್ಥ ಪ್ರಭವತಿ ಅಹಃ ಆಗಮೇ -ಪಾರ್ಥಾ, ಅದೇ ಪಂಚಭೂತಗಳ ಗುಂಪು\nಮರಳಿಮರಳಿ ಹುಟ್ಟಿ ಇರುಳಾದಾಗ ಭಗವಂತನ ವಶದಲ್ಲಿ ಲಯಗೊಳ್ಳುತ್ತದೆ; ಹಗಲಾದಾಗ ಹುಟ್ಟುತ್ತದೆ.\n\nಸೃಷ್ಟಿಯ ಮೂಲದ್ರವ್ಯ ಎಂದೂ ಬದಲಾಗುವುದಿಲ್ಲ. ಅದೇ ಪಂಚಭೂತಗಳು ಮರಳಿಮರಳಿ ಸೃಷ್ಟಿ-ಸಂಹಾರ\nಚಕ್ರದಲ್ಲಿ ಸುತ್ತುತ್ತಿರುತ್ತವೆ. ಈ ಚಕ್ರದಲ್ಲಿ ಮೋಕ್ಷ ಯೋಗ್ಯವಲ್ಲದ ಅನಂತ ಜೀವಗಳೂ ಸುತ್ತುತ್ತಿರುತ್ತವೆ. ಆದರೆ\nಭಗವಂತನನ್ನು ಸೇರಿದ ಜೀವ ಈ ಚಕ್ರದಿಂದಾಚೆಗಿರುತ್ತದೆ.\n",
  "8.20": "ಪರಃ ತಸ್ಮಾತ್‌ ತು ಭಾವಃ ಅನ್ಯಃ ಅವ್ಯಕ್ತಃ ಅವ್ಯಕ್ತಾತ್‌ ಸನಾತನಃ ।\nಯಃ ಸಃ ಸರ್ವೇಷು ಭೂತೇಷು ನಶ್ಯತ್ಸು ನ ವಿನಶ್ಯತಿ -ಈ ಕಾಣುವ ವಿಶ್ವಕ್ಕಿಂತ ಬೇರೆಯಾಗಿ, ಮಿಗಿಲಾಗಿ\nಎಂದೆಂದೂ ಇರುವ ತತ್ವವೇ ಅವ್ಯಕ್ತ. ಎಲ್ಲಾ ಭೂತಗಳು ಇಲ್ಲವಾದಾಗಲೂ ಅದು ಇರುತ್ತದೆ.\n\nಎಲ್ಲವನ್ನೂ ಮೀರಿ ನಿಂತ ಭಗವಂತ ಎಲ್ಲಕ್ಕೆಂತ ವಿಲಕ್ಷಣ ಮತ್ತು ಶ್ರೇಷ್ಠ. ಆತ ಸನಾತನ. ಎಲ್ಲಾ ಕಾಲದಲ್ಲೂ\nನಿರ್ವಿಕಾರನಾಗಿರುವ, ಸರ್ವವೇದ ಪ್ರತಿಪಾಧ್ಯ, ಸಮಸ್ತ ಚರಾಚರಾತ್ಮಕ ಪ್ರಪಂಚ ನಾಶವಾದಾಗಲೂ\n\nನಾಶವಾಗದೇ ಎಲ್ಲವನ್ನೂ ತನ್ನಲ್ಲಿ ಲೀನವಾಗಿಸಿಕೊಂಡು ಇರುವ ಏಕಮಾತ್ರ ತತ್ವ ಭಗವಂತ.\n",
  "8.21": "ಅವ್ಯಕ್ತಃ ಅಕ್ಷರಃ ಇತಿ ಉಕ್ತಃ ತಮ್‌ ಆಹುಃ ಪರಮಾಮ್‌ ಗತಿಮ್‌ |\n\nಯಮ್‌ ಪ್ರಾಪ್ಯ ನ ನಿವರ್ತಂತೇ ತತ್‌ ಧಾಮ ಪರಮಮ್‌ ಮಮ -ಈ ಅವ್ಯಕ್ತ ತತ್ವವನ್ನೇ “ಅಕ್ಷರ' ನಾದ\nಭಗವಂತನೆನ್ನುತ್ತಾರೆ. ಅವನೇ ಕೊನೆಯಾಸರೆ ಎನ್ನುತ್ತಾರೆ. ಅವನನ್ನು ಪಡೆದವರು ಮತ್ತೆ ಮರಳಿ ಬರುವುದಿಲ್ಲ.\nಅದು ನನ್ನ ಹಿರಿದಾದ ಸ್ವರೂಪ.\n\nಎಲ್ಲರೂ ಹೋಗಿ ಸೇರಬೇಕಾದ ಸರ್ವಶ್ರೇಷ್ಠ ಸ್ಥಾನ ಈ ಅವ್ಯಕ್ತ ತತ್ವ. ಆತನೇ 'ಅಕ್ಷರ' ಶಬ್ದದ ಮುಖ್ಯಾರ್ಥ.\nಎಂದೂ ನಾಶವಿಲ್ಲದ, ಎಲ್ಲಾ ಕಡೆ ವ್ಯಾಪಿಸಿರುವ, ಯಾರು ಏನು ಬಯಸಿದರೂ ಅದನ್ನು ಕೊಡತಕ್ಕ,\nಸರ್ವಸಮರ್ಥ, ಇಂದ್ರಿಯಗಳ ಅನುಭವ ಕೊಡುವವ, ಸಮಸ್ತ ಶಬ್ದವಾಚ್ಯ-ಭಗವಂತ. ಅವನನ್ನು ಸೇರಿದರೆ ಮತ್ತೆ\nಮರಳಿ ಸಂಸಾರದಲ್ಲಿ ಹುಟ್ಟಬೇಕಾಗಿಲ್ಲ. “ಅದು ನನ್ನ ಹಿರಿದಾದ ಸ್ವರೂಪ” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.\n\nಪುರುಷಃ ಸ ಪರಃ ಪಾರ್ಥ ಭಕ್ತ್ಯಾ ಲಭ್ಯಸ್ತ್ರನನ್ಯಯಾ |",
  "8.22": "'ಪಾರ್ಥಾ, ಯಾವ ಪರಮ ಪುರುಷನಲ್ಲಿ ಸಮಸ್ತ ಜೀವಿಗಳು ನೆಲೆಸಿವೆಯೋ ಮತ್ತು ಯಾರಿಂದ ಈ ಜಗತ್ತೆಲ್ಲವೂ ವ್ಯಾಪ್ತವಾಗಿದೆಯೋ, ಆ ಪರಮ ಪುರುಷನು ಅನನ್ಯ ಭಕ್ತಿಯಿಂದ ಮಾತ್ರ ಲಭ್ಯನಾಗುತ್ತಾನೆ.'\n\n'ಅನನ್ಯಯಾ ಭಕ್ತ್ಯಾ' — ಅನನ್ಯ ಭಕ್ತಿ — ಇದೊಂದೇ ಮಾರ್ಗ. 'ಯಸ್ಯಾಂತಃಸ್ಥಾನಿ ಭೂತಾನಿ' — ಯಾರಲ್ಲಿ ಎಲ್ಲಾ ಜೀವಿಗಳು ನೆಲೆಸಿವೆಯೋ. 'ಯೇನ ಸರ್ವಮಿದಂ ತತಮ್' — ಯಾರಿಂದ ಇದೆಲ್ಲವೂ ವ್ಯಾಪಿಸಿದೆಯೋ. ಇದು ಧ್ಯಾನಯೋಗ ಅಧ್ಯಾಯದ ಪರಮ ಮುಕ್ತಾಯ.",
  "8.23": "ಯತ್ರ ಕಾಲೇ ತು ಅನಾವೃತ್ತಿಮ್‌ ಆವೃತ್ತಿಮ್‌ ಚ ಏವ ಯೋಗಿನಃ |\n\nಪ್ರಯಾತಾಃ ಯಾಂತಿ ತಮ್‌ ಕಾಲಮ್‌ ವಕ್ಷ್ಯಾಮಿ ಭರತ ಋಷಭ -ಭರತ ಶ್ರೇಷ್ಠಾ, ಯಾವ ಕಾಲದೇವತೆಗಳ\nದಾರಿಯಲ್ಲಿ ಹೋದ ಸಾಧಕರು ಮರಳಿ ಬರುವುದಿಲ್ಲ ಮತ್ತು ಯಾವ ದಾರಿಯಲ್ಲಿ ಮರಳಿಬರುತ್ತಾರೆ ಅಂತಹ\nಕಾಲದೇವತೆಗಳನ್ನು ಹೇಳುತ್ತೇನೆ.\n\n“ಶರೀರವನ್ನು ತ್ಯಾಗ ಮಾಡಿದ(ಕಾಲ ವಶನಾದ) ಜೀವನನ್ನು ಯಾವಯಾವ ದೇವತೆಗಳು ನಿಯಮನ ಮಾಡಿ\nಮುಂದೆ ಕರೆದುಕೊಂಡು ಹೋಗುತ್ತಾರೆ; ಯಾವ ದಾರಿಯಲ್ಲಿ ಹೋದವರು ಮರಳಿ ಭೂಮಿಯಲ್ಲಿ ಹುಟ್ಟುತ್ತಾರೆ\nಮತ್ತು ಯಾರು ನೇರವಾಗಿ ಮೋಕ್ಷವನ್ನು ತಲುಪುತ್ತಾರೆ, ಆ ವಿಷಯವನ್ನು ನಿನಗೆ ಹೇಳುತ್ತೇನೆ” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.\nಇಲ್ಲಿ ಕೆಲವರು ಕಾಲ ಎನ್ನುವ ಪದವನ್ನೂ ತಪ್ಪಾಗಿ ತಿಳಿದುಕೊಳ್ಳುತ್ತಾರೆ. ಈ ಶ್ಲೋಕದಲ್ಲಿ ಕೃಷ್ಣ ಹೇಳುವ ಕಾಲ\nಅಂದರೆ ಸಮಯವಲ್ಲ. ಶರೀರ ತ್ಯಾಗ ಮಾಡಿದ ಜೀವದ ನಿಯಮನ ಮಾಡುವ ದೇವತೆಗಳ ಗಣ “ಕಾಲ”,\n",
  "8.24": "ಅಗ್ನಿಃ ಜ್ಯೋತಿಃ ಅಹಃ ಶುಕ್ಲಃ ಷಟ್‌ ಮಾಸಾಃ ಉತ್ತರ ಅಯನಮ್‌,।\n\nತತ್ರ ಪ್ರಯಾತಾಃ ಗಚ್ಛಂತಿ ಬ್ರಹ್ಮ ಬ್ರಹ್ಮವಿದಃ ಜನಾಃ -ಅಗ್ನಿ ಮತ್ತು ಜ್ಯೋತಿ [ಎಂಬಿಬ್ಬರು ವಹ್ನಿಯ\nಮಕ್ಕಳು].[ಮಧ್ಯಾಹ್ನದ ದೇವತೆಯ ಜತೆ] ಹಗಲಿನ ದೇವತೆ, [ಹುಣ್ಣಿಮೆಯ ದೇವತೆ ಜತೆ] ಶುಕ್ಲಪಕ್ಷದ ದೇವತೆ ,\nಉತ್ತರಾಯಣದ ಆರು ತಿಂಗಳ ದೇವತೆಗಳು, [ಸಂಕ್ರಾಂತಿಯ ದೇವತೆಯ ಜತೆ] ಉತ್ತರಾಯಣದ ದೇವತೆ- ಈ\nದಾರಿಯಲ್ಲಿ ಹೋದವರು ಭಗವಂತನನ್ನು ಬಲ್ಲವರು ಭಗವಂತನನ್ನು ಸೇರುತ್ತಾರೆ; ಮತ್ತೆ ಮರಳುವುದಿಲ್ಲ.\n\nದೇಹದಿಂದ ಹೊರಬಂದ ಮೋಕ್ಷ ಯೋಗ್ಯ ಜೀವವನ್ನು ಮೊದಲು ಸ್ವಾಗತಿಸುವವರು ವೈಶ್ವಾನರ(ಪ್ರಧಾನ\nಅಗ್ನಿ)ನ ಮಕ್ಕಳಾದ ಅಗ್ನಿ ಮತ್ತು ಜ್ಯೋತಿ. ಈ ದೇವತೆಗಳು ಜೀವನನ್ನು ಸತ್ಕರಿಸಿ ಮುಂದಕ್ಕೆ ಕಳುಹಿಸುತ್ತಾರೆ.\nಮುಂದೆ ಜೀವನನ್ನು ಬೆಳಕಿನ ಮತ್ತು ಮಧ್ಯಾಹ್ನದ ದೇವತೆಗಳು ಸ್ವಾಗತಿಸುತ್ತಾರೆ. ಈ ನಿಜವಾದ ಬೆಳಕಿನ\nಅನುಭವದೊಂದಿಗೆ ಜೀವ ಮುಂದೆ ಸಾಗಿ ಶುಕ್ಲಪಕ್ಷದ ಮತ್ತು ಹುಣ್ಣಿಮೆಯ ದೇವತೆಯನ್ನು ತಲುಪುತ್ತಾನೆ. ಆ\nನಂತರ ಸಂಕ್ರಮಣದ, ಉತ್ತರಾಯಣದ ದೇವತೆ ಜೊತೆಗೆ ಉತ್ತರಾಯಣದ ಆರು ತಿಂಗಳ ದೇವತೆಗಳು\nಜೀವನನ್ನು ಭಗವಂತನೆಡೆಗೆ ಕಳುಹಿಸುತ್ತಾರೆ. ಹೀಗೆ ಯಾರು ಈ ದಾರಿಯಲ್ಲಿ ಸಾಗುತ್ತಾರೋ ಅವರು ಎಂದೂ\nಮರಳಿ ಬರುವುದಿಲ್ಲ-ನಿತ್ಯ ಸತ್ಯವಾದ ಭಗವಂತನನ್ನು ಸೇರುತ್ತಾರೆ.",
  "8.25": "ಧೂಮಃ ರಾತ್ರಿಃ ತದಾ ಕೃಷ್ಣಃ ಷಟ್‌ ಮಾಸಾ ದಕ್ಷಿಣಾಯನಮ್‌ |\n\nತತ್ರ ಚಾಂದ್ರಮಸಮ್‌ ಜ್ಯೋತಿಃ ಯೋಗೀ ಪ್ರಾಪ್ಯ ನಿವರ್ತತೇ -ಹೊಗೆಯ ದೇವತೆ, ಇರುಳ ದೇವತೆ,\nಕೃಷ್ಣಪಕ್ಷದ ದೇವತೆ, ದಕ್ಷಿಣಾಯನದ ಆರು ತಿಂಗಳ ದೇವತೆಗಳು, ಮತ್ತು ದಕ್ಷಿಣಾಯನದ ದೇವತೆ-ಈ ದಾರಿಯಲ್ಲಿ\nಸಾಗಿದ ಸಾಧಕ ಚಂದ್ರನ ಬೆಳಕಿನ ಲೋಕವನ್ನು ಸೇರಿ ಮರಳಿ ಬರುತ್ತಾನೆ.\n\nಮೋಕ್ಷ ಯೋಗ್ಯವಲ್ಲದ ಜೀವ ದೇಹದಿಂದ ಹೊರ ಬಂದಾಗ ಆತನನ್ನು ಸ್ವಾಗತಿಸುವ ದೇವತೆ ಹೊಗೆಯ ಮತ್ತು\nಕತ್ತಲಿನ ದೇವತೆ. ಆ ನಂತರ ಕೃಷ್ಣಪಕ್ಷದ ದೇವತೆ; ನಂತರ ದಕ್ಷಿಣಾಯನದ ಮತ್ತು 'ದಕ್ಷಿಣಾಯನದ ಆರು\nತಿಂಗಳ' ದೇವತೆಗಳು ಜೀವನನ್ನು ಸೋಮಲೋಕಕ್ಕೆ ತಲುಪಿಸುತ್ತಾರೆ. ಜೀವ ಇಲ್ಲಿ ತನ್ನ ಪುಣ್ಯ ಕ್ಷಯವಾಗುವ\nತನಕ ಸುಖವನ್ನು ಅನುಭವಿಸಿ, ಮರಳಿ ಮೋಡದಲ್ಲಿ ಸೇರಿ, ಮಳೆಯ ಮೂಲಕ ಭೂಮಿಯನ್ನು ತಲುಪಿ, ಒಂದು\nಗಂಡಿನ ದೇಹದ ಮೂಲಕ ಹೆಣ್ಣಿನ ಗರ್ಭವನ್ನು ಪ್ರವೇಶಿಸಿ, ಮರಳಿ ಭೂಮಿಯಲ್ಲಿ ಹುಟ್ಟುತ್ತದೆ.",
  "8.26": "ಶುಕ್ಲ ಕೃಷ್ಣೇ ಗತೀ ಹಿ ಏತೇ ಜಗತಃ ಶಾಶ್ವತೇ ಮತೇ ।\n\nಏಕಯಾ ಯಾತಿ ಅನಾವೃತ್ತಿಮ್‌ ಅನ್ಯಯಾ ಆವರ್ತತೇ ಪುನಃ -ಇವು ಜಗದ ಬಿಳಿ ಮತ್ತು ಕಪ್ಪು ದಾರಿಗಳು.\nಅನುಗಾಲ ಇರುವಂತವು ಎಂದು ಶಾಸ್ತ್ರದ ತೀರ್ಮಾನ. ಒಂದರಿಂದ ಮರಳಿ ಬರುವುದಿಲ್ಲ. ಇನ್ನೊಂದರಿಂದ\nಮತ್ತೆ ಮರಳುತ್ತಾನೆ.\n\nಹೀಗೆ ಒಂದು ಮೋಕ್ಷಕ್ಕೆ ಹೋಗುವ ಬೆಳಕಿನ ಬಿಳಿಯ ದಾರಿ ಮತ್ತು ಇನ್ನೊಂದು ಮರಳಿ ಸಂಸಾರಕ್ಕೆ ಬರುವ\nಕತ್ತಲಿನ ಕಪ್ಪು ದಾರಿ. ಈ ಎರಡೂ ದಾರಿಗಳು ಅನಾದಿ ಅನಂತ ಕಾಲದಲ್ಲಿ ಎಲ್ಲಾ ಜೀವಗಳಿಗೆ ಸಮನಾಗಿ\nಇರತಕ್ಕಂತಹ ವ್ಯವಸ್ಥೆ. ಬೆಳಕಿನ ದಾರಿಯಲ್ಲಿ ಹೋದವ ಮರಳಿ ಬರುವುದಿಲ್ಲ, ಕತ್ತಲೆಯ ದಾರಿಯಲ್ಲಿ ಹೋದವ\nಮರಳಿ ಬರುತ್ತಾನೆ.\n",
  "8.27": "ನ ಏತೇ ಸೃತೀ ಪಾರ್ಥ ಜಾನನ್‌ ಯೋಗೀ ಮುಹ್ಯತಿ ಕಶ್ಚನ |\nತಸ್ಮಾತ್‌ ಸರ್ವೇಷು ಕಾಲೇಷು ಯೋಗಯುಕ್ತಃ ಭವ ಅರ್ಜುನ- ಪಾರ್ಥಾ, ಈ ದಾರಿಗಳನ್ನ ರಿತ ಯಾವ\nಸಾಧಕನೂ ದಾರಿ ತಪ್ಪುವುದಿಲ್ಲ. ಆದ್ದರಿಂದ, ಓ ಅರ್ಜುನಾ, ಎಲ್ಲಾ ಕಾಲಗಳಲ್ಲೂ ಉಪಾಯವನ್ನರಿತು ನಡೆ.\n\nಈ ಎರಡೂ ದಾರಿಗಳ ಬಗ್ಗೆ ಸರಿಯಾದ ತಿಳುವಳಿಕೆ ಇದ್ದು, ನೀನು ಹೋಗಬೇಕಾದ ದಾರಿ ಯಾವುದು ಎಂದು\nತಿಳಿದು, ಆಯಾ ಅಭಿಮಾನಿ ದೇವತೆಗಳ ಜೊತೆಗೆ ಮುಂದಕ್ಕೆ ಸಾಗಬೇಕು. ಆಯಾ ಅಭಿಮಾನಿ ದೇವತೆಗಳು\nಬೇರೆಬೇರೆ ಮೆಟ್ಟಲಿನಲ್ಲಿ ಬಂದು ಜೀವನನ್ನು ಮುಂದಕ್ಕೆ ಕರೆದುಕೊಂಡು ಹೋಗುತ್ತಾರೆ. ಈ ಕಾರಣದಿಂದ ಅಂತ್ಯ\nಕಾಲದ ಸ್ಮರಣೆಯಲ್ಲಿ ಮಾರ್ಗ ಮತ್ತು ಅಭಿಮಾನಿ ದೇವತೆಗಳ ಚಿಂತನೆ ಅತ್ಯಗತ್ಯ. ಇದನ್ನು ತಿಳಿದು\nಅನುಸಂಧಾನ ಮಾಡಿಕೊಂಡು ಅನುಷ್ಠಾನ ಮಾಡಿದರೆ ಯಾವ ಸಾಧಕನಿಗೂ ಗೊಂದಲವಿಲ್ಲ. ಆದ್ದರಿಂದ ಕೃಷ್ಣ\nಅರ್ಜುನನಿಗೆ ಹೇಳುತ್ತಾನೆ - “ಎಲ್ಲಾ ಕಾಲದಲ್ಲೂ ಈ ಉಪಾಯವನ್ನರಿತು ನಡೆ” ಎಂದು.\n",
  "8.28": "ವೇದೇಷು ಯಜ್ಞೇಷು ತಪಸ್ಸು ಚ ಏವ ದಾನೇಷು ಯತ್‌ ಪುಣ್ಯಫಲಮ್‌ ಪ್ರದಿಷ್ಟಮ್‌ ।\n\nಅತ್ಯೇತಿ ತತ್‌ ಸರ್ವಮ್‌ ಇದಮ್‌ ವಿದಿತ್ವಾ ಯೋಗೀ ಪರಮ್‌ ಸ್ಥಾನಮ್‌ ಉಪೈತಿ ಚ ಆದ್ಯಮ್‌ -ವೇದವನ್ನು\nಓದಿದರೆ, ಯಜ್ಞಗಳನ್ನು ಮಾಡಿದರೆ, ತಪಗಳನ್ನು ಆಚರಿಸಿದರೆ, ದಾನಗಳನ್ನು ನೀಡಿದರೆ ಏನು ಪುಣ್ಯಫಲ\nಹೇಳಲಾಗಿದೆಯೋ ಅದನ್ನೆ ಲ್ಲಾ ಮೀರಿ ನಿಲ್ಲುತ್ತಾನೆ ಇದನ್ನು ಬಲ್ಲ ಸಾಧಕ; ಎಲ್ಲಕ್ಕೂ ಮೊದಲ ಹಿರಿಯ ತಾಣವನ್ನು\n\nಸೇರುತ್ತಾನೆ.\n\nಉಪಸಂಹಾರ ಮಾಡುತ್ತಾ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ-ಎಲ್ಲಕ್ಕೆಂತ ಮಿಗಿಲಾದ ತಿಳಿವು ಅಂದರೆ ಈ ಅಂತ್ಯ ಕಾಲದ\nಅರಿವು ಎಂದು . ಸಮಸ್ತ ಶಾಸ್ತ್ರದಲ್ಲಿ ಯಜ್ಞ-ದಾನ-ತಪಸ್ಸುಗಳ ಮೂಲಕ ಏನು ಪುಣ್ಯ ಹೇಳಿದ್ದಾರೆ, ಈ ಅಂತ್ಯ\nಕಾಲದ ಸಾವಿನ ರಹಸ್ಯದ ಅರಿವು ಈ ಎಲ್ಲಾ ಪುಣ್ಯ ಫಲವನ್ನು ಮೀರಿ ನಿಲ್ಲುತ್ತದೆ. ಆದ್ದರಿಂದ ಎಲ್ಲಕ್ಕೆಂತ ದೊಡ್ಡ\nಸಾಧನೆ ಅಂತ್ಯ ಕಾಲದ ಚಿಂತನೆ. ಈ ಕಾರಣದಿಂದ ಬದುಕಿಗಿಂತ ಸಾವಿನ ಬಗ್ಗೆ ಹೆಚ್ಚು ಚಿಂತನೆಯ ಅಗತ್ಯವಿದೆ.\n\nಸಾವು ಅಮಂಗಳವಲ್ಲ. ಸಾವು ದುಃಖದ ಅನುಭವ ಎನ್ನುವುದು ನಮ್ಮ ಭ್ರಮೆ. ದೇಹದ ಒಳಗಿರುವಾಗ ಭೌತಿಕ\nಶರೀರದ ಎಲ್ಲಾ ಯಾತನೆ ಜೀವಕ್ಕೆ ಅಂಟಿಕೊಂಡಿರುತ್ತದೆ. ಸಾವು ಎಂದರೆ ಈ ಸ್ಥೂಲ ಶರೀರದಿಂದ ಬಿಡುಗಡೆ.\nಆದ್ದರಿಂದ ಸೂಕ್ಷ್ಮ ಶರೀರದಲ್ಲಿರುವ ಜೀವ ಪಂಜರದಿಂದ ಹೊರ ಬಂದು ಮುಕ್ತವಾಗಿ ಆಕಾಶದಲ್ಲಿ ಹಾರಾಡುವ\n\nಪಕ್ಷಿಯಂತೆ. ಈ ಕಾರಣದಿಂದ ಸಾವಿನ ಭಯ ಬಿಟ್ಟು ಕೊನೇ ಕ್ಷಣದಲ್ಲಿ ಮಾಂಗಲಿಕವಾಗಿ ಎತ್ತರಕ್ಕೇರುವ\nದೇವತಾ ಅನುಸಂಧಾನ ನಿರಂತರವಾಗಿ ನಮ್ಮ ಬದುಕಿನಲ್ಲಿರಬೇಕು.\n\nಇತಿ ಅಷ್ಟ ಮೋಧ್ಯಾಯಃ\nಎಂಟನೆಯ ಅಧ್ಯಾಯ ಮುಗಿಯಿತು\n\nಅಧ್ಯಾಯ ಒಂಬತ್ತು\n\nಜ್ಞಾನ ಎಂದರೆ ಭಗವಂತನ ಅರಿವು(Knowledge of God). ಎಲ್ಲವನ್ನು ತಿಳಿದ ಭಗವಂತನೆಡೆಗೆ ನಮ್ಮ ಮನಸ್ಸು\nಹರಿಯುವುದು ಜ್ಞಾನ. ಭಗವಂತ ಸರ್ವೋತ್ತಮ, ಸರ್ವಗತ, ಸರ್ವಜ್ಞ, ಇತ್ಯಾದಿಯಾಗಿ ತಿಳಿಯುವುದು ಜ್ಞಾನ. ಆ\nನಂತರ ಅದರ ವಿವರಗಳ ಅರಿವು ವಿಜ್ಞಾನ(ವಿಶಿಷ್ಟವಾದ ಜ್ಞಾನ). ಭಗವಂತ ಗುಣಪೂರ್ಣ ಎನ್ನುವುದು ಜ್ಞಾನ.\nಭಗವಂತ ಜ್ಞಾನಪೂರ್ಣ, ಆನಂದಪೂರ್ಣ, ಸೌಂದರ್ಯಪೂರ್ಣ, ದಯಾಪೂರ್ಣ, ಹೀಗೆ ಒಂದೊಂದು ಗುಣಗಳ\nಪೂರ್ಣತೆಯನ್ನು ವಿವರವಾಗಿ ಅನುಸಂಧಾನ ಮಾಡುವುದು ವಿಜ್ಞಾನ(Experiential Knowledge). ನಾವು\nದೇವರನ್ನು ಪೂರ್ಣವಾಗಿ ಅರಿಯಲು ಸಾಧ್ಯವಿಲ್ಲ. ಆದರೆ ಪ್ರತಿಯೊಂದು ಜೀವನಿಗೆ ಒಂದು ವಿಶಿಷ್ಟವಾದಂತಹ\nಅರಿವಿನ ಮಟ್ಟವಿರುತ್ತದೆ. ಎಲ್ಲರೂ ಒಂದೇ ರೀತಿ ತಿಳಿದುಕೊಳ್ಳಲು ಬರುವುದಿಲ್ಲ. ಅವರವರ ಮಟ್ಟಕ್ಕೆ ತಕ್ಕಂತೆ\nಭಗವಂತನನ್ನು ಅರಿಯುವುದು ವಿಜ್ಞಾನ(Integrated Experiential Knowledge). ಹೀಗೆ ಭಗವಂತ\nಸರ್ವೋತ್ತಮ ಎಂದು ತಿಳಿದುಕೊಳ್ಳುವುದು ಜ್ಞಾನವಾದರೆ, ಆ ಸರ್ವೋತ್ತಮ ತತ್ವವನ್ನು ವಿವರವಾಗಿ ಅದರ\nಬೇರೆ ಬೇರೆ ಮುಖಗಳಿಂದ ಅವರವರ ಯೋಗ್ಯತೆಗೆ ತಕ್ಕಂತೆ ಅನುಸಂಧಾನ ಮಾಡುವುದು ವಿಜ್ಞಾನ. ಹೀಗೆ\nಅನುಸಂಧಾನ ಮಾಡುವುದರಿಂದ ಭಗವಂತ ಅಲ್ಲವುದಕ್ಕಿಂತ ವಿಲಕ್ಷಣ ಎನ್ನುವ ಸತ್ಯದ\nಸಾಕ್ಷಾತ್ಕಾರವಾಗುತ್ತದೆ.\n\nಕೃಷ್ಣ ಏಳನೇ ಅಧ್ಯಾಯದಲ್ಲಿ ಅರ್ಜುನನಿಗೆ ಹೇಳಿದ್ದ- “ತಿಳಿಯಬೇಕಾದ ನನ್ನ ಹಿರಿಮೆಯನ್ನು ಅದರ ಬಿತ್ತರದ\nಜತೆಗೆ ನಿನಗೆ ನಾನು ಪೂರ್ತಿಯಾಗಿ ಹೇಳುತ್ತೇನೆ. ಇದನ್ನು ತಿಳಿದರೆ ಮತ್ತೆ ಈ ವಿಷಯದಲ್ಲಿ ಬೇರೆ\nತಿಳಿಯುವಂತಹದ್ದೇನೂ ಉಳಿದಿರುವುದಿಲ್ಲ” ಎಂದು (ಅ-೭ , ಶ್ಲೋ-೨). ಮತ್ತೆ ಇಲ್ಲಿ ಈ ಅಧ್ಯಾಯದಲ್ಲಿ ಪುನಃ\nಜ್ಞಾನ ವಿಜ್ಞಾನದ ಬಗ್ಗೆ ವಿವರಿಸುತ್ತಾನೆ! . ಏಕೆ ಹೀಗೆ? ಹಿಂದೆ ಹೇಳಿದ್ದನ್ನು ಕೃಷ್ಣ ಮರೆತು ಪುನಃ\nವಿವರಿಸುತ್ತಿದ್ದಾನೋ?! ಅಲ್ಲ, ಅದಕ್ಕೆ ಕಾರಣಗಳಿವೆ. ಒಮ್ಮೆ ಹೇಳಿದ್ದನ್ನು ಮತ್ತೆ ಏಕೆ ಹೇಳುತ್ತಿದ್ದಾನೆ ಎಂದರೆ\n\"ಬೇರೆಬೇರೆ ಆಯಾಮದಲ್ಲಿ ಹೇಳುವುದಕ್ಕೋಸ್ಕರ'. ಆದ್ದರಿಂದ ಇಲ್ಲಿ ಹೇಳುವುದು ಹಿಂದೆ ಹೇಳಿದುದರ ವಿವರಣೆ\nಮತ್ತು ಸೃಷ್ಟೀಕರಣ. ಸಂಕ್ಷಿಪ್ತವಾಗಿ ಅಲ್ಲಿ ವಿವರಿಸಿದ್ದನ್ನು ಇಲ್ಲಿ ಕೆಲವು ಹೊಸ ಅರ್ಥಗಳಿಂದ ಇನ್ನೊಂದು ರೀತಿಯಲ್ಲಿ\nಕೃಷ್ಣ ವಿವರಿಸುತ್ತಾನೆ. ಭಗವಂತನ ತತ್ವ ಚಿಂತನೆಯನ್ನು ಒಂದು ಬಾರಿ ಮಾಡಿದರೆ ನಮ್ಮ ತಲೆಯೊಳಗೆ\nಹೋಗುವುದಿಲ್ಲ! ನಿರಂತರ ಚಿಂತನೆ ಮಾಡುತ್ತಾ ಇದ್ದರೆ ಎಲ್ಲೋ ಸ್ವಲ್ಪ ಒಳಗೆ ಹೋಗುತ್ತದೆ! ಕೇಳಿದಾಗ,\nಓದಿದಾಗ ಎಲ್ಲವೂ ತಿಳಿಯಿತು ಅನಿಸುತ್ತದೆ. ಆದರೆ ಸ್ವಲ್ಪ ಹೊತ್ತಿನ ನಂತರ ಒಂದೂ ನೆನಪಾಗುವುದಿಲ್ಲ!\nಅದಕ್ಕೋಸ್ಕರ ಆವೃತ್ತಿ ಮಾಡುತ್ತಾ ಬೇರೆಬೇರೆ ಆಯಾಮದಲ್ಲಿ ಚಿಂತನೆ ಮಾಡಬೇಕು. ಈ ಅಧ್ಯಾಯದಲ್ಲಿ ಕೃಷ್ಣ\nಹಿಂದೆ ಹೇಳಿದ್ದ ಜ್ಞಾನ-ವಿಜ್ಞಾನವನ್ನು ನಮಗೆ ಅರ್ಥವಾಗುವ ರೀತಿಯಲ್ಲಿ ಬೇರೆಬೇರೆ ಮುಖಗಳಿಂದ ಬೇರೆಬೇರೆ\nಆಯಾಮದಲ್ಲಿ ವಿವರಿಸುತ್ತಾನೆ.\n\nಒಬ್ಬ ಸೈನಿಕನಾಗಿ ಯುದ್ಧರಂಗದಲ್ಲಿ ನಿಂತಿರುವ ವ್ಯಕ್ತಿಯ ಮಾನಸಿಕ ಸ್ಥಿತಿ ಅಧ್ಯಾತ್ಮ ಚಿಂತನೆಗೆ ಬಹಳ\nಹತ್ತಿರವಾಗಿರುತ್ತದೆ. ಈ ಕಾರಣದಿಂದ ಯುದ್ಧರಂಗದಲ್ಲಿ ಕೃಷ್ಣ ಅಧ್ಯಾತ್ಮವನ್ನು ಬಿಚ್ಚುತ್ತಾನೆ. ಅರ್ಜುನ ಬಹಳ\nದೊಡ್ಡ ಜ್ಞಾನಿ. ಸದಾ ಭಗವದ್‌ ಚಿಂತನೆಯಲ್ಲಿ ಇರತಕ್ಕಂತಹ ದೇವಾಂಶಸಂಭೂತ. ಅದರ ಜೊತೆಗೆ ಆತನನ್ನು\nಯುದ್ಧರಂಗದಲ್ಲಿ ನಿಲ್ಲಿಸಿ, ಮಾನಸಿಕವಾಗಿ ಹುಟ್ಟು ಸಾವುಗಳ ಈ ಲೀಲೆಯ ಆಚೆಗೆ ಅವನನ್ನು ಕರೆದೊಯ್ದು,\n\nಮಾನಸಿಕವಾಗಿ ಅಣಿಗೊಳಿಸಿ-ಕೃಷ್ಣ ವೇದಾಂತವನ್ನು ಹೇಳುತ್ತಾನೆ. ಇಂತಹ ಕ್ಷಣದಲ್ಲಿ ಭಗವಂತನ ಬಗೆಗೆ\nಹೇಳಿದರೆ ಬಹುಬೇಗ ಹೃದಯ ತುಂಬಿಕೊಳ್ಳುತ್ತದೆ. ನಾವಾದರೂ ಅಷ್ಟೇ, ನಮ್ಮ ದೈನಂದಿನ ಜೀವನದಲ್ಲಿ ಸರಿ-\nತಪ್ಪು, ಧರ್ಮಾಧರ್ಮಗಳ ಸಂಘರ್ಷ ನಡೆಯುತ್ತಲೇ ಇರುತ್ತದೆ. ಅಂತಹ ಯುದ್ಧದ ಸಂದರ್ಭದಲ್ಲೇ ನಮಗೆ\nಅಧ್ಯಾತ್ಮ ಅರ್ಥವಾಗುವುದು.\nಭಗವಾನುವಾಚ ।\nಇದಂ ತು ತೇ ಗುಹ್ಯತಮಂ ಪ್",
  "9.1": "ಭಗವಾನ್‌ ಉವಾಚ-ಭಗವಂತ ಹೇಳಿದನು:\n\nಇದಮ್‌ ತು ತೇ ಗುಹ್ಯತಮಮ್‌ ಪ್ರವಕ್ಷ್ಯಾಮಿ ಅನಸೂಯವೇ।\n\nಜ್ಞಾನಮ್‌ ವಿಜ್ಞಾನ ಸಹಿತಮ್‌ ಯತ್‌ ಜ್ಞಾತ್ವಾ ಮೋಕ್ಷ್ಯಸೇ ಅಶುಭಾತ್‌- ಇದಂತೂ ತುಂಬಾ\nಬಚ್ಚಿಡಬೇಕಾದದ್ದು. ಕಿಚ್ಚು ಪಡದೆ ಮೆಚ್ಚುವವನೆಂದು ಹೇಳುತ್ತಿದ್ದೇನೆ: ತಿಳಿವು ಮತ್ತು ತಿಳಿವಿನ ಬಿತ್ತರ. ಇದನ್ನು\nತಿಳಿದು ಕುತ್ತಿನಿಂದ ಪಾರಾಗುವೆ.\n\nಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಭಗವದ್‌ ತತ್ವದ ಬಗೆಗೆ ನಿನಗೆ ಪುನಃ ಹೇಳುತ್ತೇನೆ; ಅತ್ಯಂತ ರಹಸ್ಯವಾದ ಉಪಾಸನೆ\nಸಂಗತಿಯನ್ನು ನಿನ್ನ ಮುಂದೆ ಬಿಚ್ಚಿಡುತ್ತಿದ್ದೇನೆ” ಎಂದು. ಇದು ಎಲ್ಲರ ಮುಂದೆ ತೆರೆದಿಡುವ ಸಂಗತಿಯಲ್ಲ.\nಯಾರಿಗೆ ಭಗವಂತನ ಉಪಾಸನೆಯಲ್ಲಿ ಅನನ್ಯವಾದ ಕಾತರ ಇರುವರರಿಗೆ, ಭಗವಂತನಲ್ಲದೆ ನನಗೆ ಇನ್ನೇನೂ\nಬೇಡ ಎನ್ನುವ ಮನಸ್ಸುಳ್ಳವರಿಗೆ ಮತ್ತು ಭಗವಂತನಿಗೋಸ್ಕರ ಹಾತೊರೆಯುವವರ ಮುಂದೆ ಹೇಳಬೇಕಾದ\nಮಾತು. ಅತ್ಯಂತ ರಹಸ್ಯವಾದ ಗೋಪನೆ ಮಾಡಬೇಕಾದ ಸಂಗತಿ. “ಅದನ್ನು ನಾನು ನಿನಗೆ ಹೇಳುತ್ತಿದ್ದೇನೆ”\nಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಇಲ್ಲಿ ಅರ್ಜುನನಿಗೆ ಈ ವಿಚಾರವನ್ನು ತಿಳಿಯುವ ಜಿಜ್ಞಾಸೆ ಮತ್ತು ಅರ್ಹತೆ ಇದ್ದುದರಿಂದ ಕೃಷ್ಣ\nಆತನಿಗೆ ಈ ಗೋಷ್ಯವಾದ ವಿಚಾರವನ್ನು ಹೇಳುತ್ತಾನೆ. ಕೇಳುವ ಅರ್ಹತೆ ಮತ್ತು ಬಯಕೆ ಇದ್ದವರಿಗೆ ಮಾತ್ರ\nಕೊಡಬೇಕಾದ ವಿದ್ಯೆ ಇದು. ಇದನ್ನು ಎಲ್ಲರಿಗೂ ಕೊಡಲಾಗುವುದಿಲ್ಲ.\n\nಇಲ್ಲಿ ಕೃಷ್ಣ “ಅನಸೂಯವೇ” ಎನ್ನುವ ಪದವನ್ನು ಬಳಸಿದ್ದಾನೆ. ಮನುಷ್ಯನಿಗೆ ವೇದಾಂತ ಓದುವ ಮತ್ತು\nವೇದಾಂತ ಓದಿದ ನಂತರವೂ ಇರಬೇಕಾದ ಗುಣ-”ಅಹಂಕಾರ ರಹಿತತೆ'(egolessness). ಅಹಂಕಾರ\nಇದ್ದು ವೇದಾಂತ ಓದಿದರೆ ಏನೂ ಉಪಯೋಗವಿಲ್ಲ. ವೇದಾಂತ ಓದುವ ಮೊದಲು ಅಹಂ ಇರಬಾರದು.\n“ಭಗವಂತನ ಮುಂದೆ ನಾನು ಏನೂ ಅಲ್ಲ” ಎಂದು ತಿಳಿದಿದ್ದರೆ ಅಹಂಕಾರ ಬರುವುದಿಲ್ಲ. ವೇದಾಂತ ಓದಿ “ನಾನು\nದೊಡ್ಡ ಜ್ಞಾನಿ' ಅನ್ನುವ ಅಹಂಕಾರ ಬಂದರೆ- ಓದಿ ದೇವರನ್ನು ಕಳೆದುಕೊಂಡಂತಾಗುತ್ತದೆ. ಆದರೆ ಇಂದು ನಾವು\nಒಂದಲ್ಲ ಒಂದು ಅಹಂಕಾರಕ್ಕೆ ಒಳಗಾಗಿರುತ್ತೇವೆ. ಜ್ಞಾನದ ಅಹಂಕಾರ, ಅಧಿಕಾರದ ಅಹಂಕಾರ, ಸಂಪತ್ತಿನ\nಅಹಂಕಾರ, ಸೌಂದರ್ಯದ ಅಹಂಕಾರ, ಯೌವನದ ಅಹಂಕಾರ, ಇಂತಹ ಅನೇಕ ಸಂಗತಿಗಳು ನಮ್ಮನ್ನು\nಕಾಡುತ್ತಿರುತ್ತವೆ. ಅದನ್ನು ಕಳಚಿಕೊಂಡಾಗ ಮಾತ್ರ ವೇದಾಂತವನ್ನು ಅರಿಯಲು ನಾವು ಅರ್ಹತೆ\n\nಪಡೆದಂತಾಗುತ್ತದೆ. ಎಲ್ಲಿಯ ತನಕ ನಮ್ಮಲ್ಲಿ ಅಹಂಕಾರ ತುಂಬಿದೆಯೋ ಅಲ್ಲಿಯ ತನಕ ವೇದಾಂತ ನಮಗೆ\nಉಪಯೋಗಕ್ಕೆ ಬರುವುದಿಲ್ಲ.\n\nಎಲ್ಲಾ ಅಹಂಕಾರಕ್ಕಿಂತ ಜ್ಞಾನದ ಅಹಂಕಾರ ಬಹಳ ಅಪಾಯಕಾರಿ. ಇತರ ಅಹಂಕಾರಕ್ಕೆ ಕೊನೆ ಇದೆ, ಆದರೆ\nಜ್ಞಾನದ ಅಹಂಕಾರಕ್ಕೆ ಕೊನೆ ಇಲ್ಲ. \"ನಾನು ಪಂಡಿತ' ಎನ್ನುವ ಅಹಂಕಾರ ತಲೆಗೆ ಬಂದರೆ ಅಂತವನು ಮಹಾ\nದರಿದ್ರ ಎನಿಸುತ್ತಾನೆ! ಅಹಂಕಾರದ ಮರಿ “ಅಸೂಯೆ'. ಈ ಅಸೂಯೆ ನಮ್ಮನ್ನು ಸುಡುವ ಬೆಂಕಿ. ಅದಕ್ಕಾಗಿ\nಅದನ್ನು ಕನ್ನಡದಲ್ಲಿ 'ಹೊಟ್ಟೆಕಿಚ್ಚು' ಎನ್ನುತ್ತಾರೆ. ಇದು ನಮ್ಮ ವ್ಯಕ್ತಿತ್ವವನ್ನು ನಾಶ ಮಾಡುತ್ತದೆ. ಅಂತವರಿಗೆ\nವೇದಾಂತ ಹೇಳಿ ಉಪಯೋಗವಿಲ್ಲ. “ ನಿನಗೆ ಅಸೂಯೆ ಇಲ್ಲ, ಅದಕ್ಕಾಗಿ ನಿನಗೆ ಈ ಗೋಪ್ಯವನ್ನು\nಹೇಳುತ್ತಿದ್ದೇನೆ” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.\n\nಯುದ್ಧ ರಂಗದಲ್ಲಿ ನಿಂತ ವ್ಯಕ್ತಿಗೆ ಅಸೂಯೆ ಇಲ್ಲದೇ ಇರುವುದು ಅತ್ಯಂತ ಮಹಾನ್‌ ಸಂಗತಿ. ದ್ವೇಷ-ಅಸೂಯೆ\nಅಹಂಕಾರಗಳು ಯುದ್ಧರಂಗದಲ್ಲಿ ಸದಾ ತುಂಬಿ ತುಳುಕುತ್ತಿರುತ್ತವೆ. ಇದನ್ನು ಗೆದ್ದು ನಿಂತವ ಅತ್ಯಂತ ಶ್ರೇಷ್ಠ.\nಇಲ್ಲಿ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಇದನ್ನು ತಿಳಿದುಕೊಂಡರೆ ನಿನ್ನ ಮನಸ್ಸು ಪರಿಶುದ್ಧವಾಗಿ ಭಗವಂತನನ್ನು\nಬಯಸುವುದು ಸಾಧ್ಯವಾಗುತ್ತದೆ” ಎಂದು. ಜ್ಞಾನ ಬಂದರೆ ನಮ್ಮೊಳಗಿನ ಕೊಳೆ ತೊಳೆದು ಹೋಗಿ ಮನಸ್ಸು\nನಿರ್ಮಲವಾಗುತ್ತದೆ. ನಮ್ಮ ಅತಿ ದೊಡ್ಡ ಸಂಪತ್ತು ಎಂದರೆ ಪ್ರಸನ್ನವಾದ ಸ್ವಚ್ಛ ಮನಸ್ಸು. ಅಂತಹ ಮನಸ್ಸಿನಲ್ಲಿ\nಭಗವಂತ ಕಾಣಿಸಿಕೊಳ್ಳುತ್ತಾನೆ. ಅಹಂಕಾರ-ಅಸೂಯೆ ಇಲ್ಲದ ಮನಸ್ಸು “ವಸುದೇವ' ಹಾಗೂ ಇಂತಹ\nಮನಸ್ಸಿಗೆ ಕಾಣುವ ಭಗವಂತ \"ವಾಸುದೇವ. ಶುದ್ಧ ಮನಸ್ಸಿನಿಂದ ಜ್ಞಾನ, ಜ್ಞಾನದಿಂದ. ಆನಂದ.\nಆನಂದಮಯವಾದ ಈ ಸ್ಥಿತಿಯಿಂದ ಪಾಂಚಭೌತಿಕ ಶರೀರದಿಂದ ಮತ್ತು ಸಂಸಾರದಿಂದ ಬಿಡುಗಡೆ ಹಾಗೂ\nಮೋಕ್ಷ.\n\nನಮಗೆ ಪಾಂಚಭೌತಿಕವಾದ ಮೂರು ಅವರಣವಿದೆ. ಈ ಮೂರು ಆವರಣದ ಒಳಗೆ ಜ್ಞಾನಾನಂದಮಯವಾದ\nಆತ್ಮಸ್ವರೂಪವಿದೆ. ಲಿಂಗಶರೀರ, ಸೂಕ್ಷ್ಮಶರೀರ ಮತ್ತು ಸ್ಥೂಲಶರೀರ ಇವು ಆತ್ಮವನ್ನು ಆವರಿಸಿರುವ\nಆವರಣಗಳು. ನಾವು. ಈ ಮೂರೂ ಅಂಗಿಗಳನ್ನು ಕಳಚಿ, ಅಶುಭದಿಂದ ಬಿಡುಗಡೆಹೊಂದಿ,\nಸ್ವರೂಪಭೂತವಾದ ನೈಜ ಸ್ಥಿತಿಯಲ್ಲಿ ಭಗವಂತನ ಮುಂದೆ ನಿಲ್ಲುವುದನ್ನು ಇಲ್ಲಿ ಕೃಷ್ಣ 'ಮೋಕ್ಷ್ಯಸೇ$ಶುಭಾತ್‌'\nಎಂದು ಸಂಕ್ಷಿಪ್ತವಾಗಿ ಹೇಳಿದ್ದಾನೆ.[ನಾವು ದೇವಸ್ಥಾನದಲ್ಲಿ ದೇವರ ಮುಂದೆ ಅಂಗಿ ತೆಗೆಯುವುದು- “ಭಗವಂತನ\nಮುಂದೆ ಹಾಕಿಕೊಂಡಿರುವ ಎಲ್ಲಾ ಆವರಣವನ್ನು ತೆಗೆದು ದೇವರ ಮುಂದೆ ಬತ್ತಲಾಗುವುದು' ಎನ್ನುವ\nಮುಖ್ಯಾರ್ಥವನ್ನು ಹೊಂದಿದೆ. ನಾವು ಭಗವಂತನ ಮುಂದೆ ಹಾಕಿಕೊಂಡ ಎಲ್ಲಾ ಮುಖವಾಡವನ್ನು ಬಿಚ್ಚಿ ಆತನ\nಮುಂದೆ ತೆರೆದುಕೊಳ್ಳಬೇಕು. ಆಗ ಆತ ನಮಗೆ ತೆರೆದುಕೊಳ್ಳುತ್ತಾನೆ.] ಹೀಗೆ ಯಾವ ರೀತಿ ಪಾಂಚಭೌತಿಕ\nಶರೀರದಿಂದ ಬಿಡುಗಡೆ ಮತ್ತು ಮೋಕ್ಷ ಎನ್ನುವ ಜ್ಞಾನ-ವಿಜ್ಞಾನವನ್ನು ಭಗವಂತ ಸಮಷ್ಠಿಯಾಗಿ ಅರ್ಜುನನಿಗೆ\nಹೇಳುವುದನ್ನುಮುಂದಿನ ಶ್ಲೋಕಗಳಲ್ಲಿ ನೋಡೋಣ.",
  "9.2": "ರಾಜವಿದ್ಯಾ ರಾಜಗುಹ್ಯಮ್‌ ಪವಿತ್ರಮ್‌ ಇದಮ್‌ ಉತ್ತಮಮ್‌ |\n\nಪ್ರತ್ಯಕ್ಷ ಅವಗಮಮ್‌ ಧರ್ಮ್ಯಮ್‌ ಸು ಸುಖಮ್‌ ಕರ್ತುಮ್‌ ಅವ್ಯಯಮ್‌-ಇದು ಅರಿವುಗಳ ಅರಸ. ಗುಟ್ಟುಗಳ\nಗುಟ್ಟು. ಮಿಗಿಲಾದ ಅಪ್ಪಟ. ಕಣ್ಣಲ್ಲಿ ಕೂತವನ ಕಾಣಿಸುವ ದಾರಿ. ಎಲ್ಲಾ ಹೊತ್ತವನನ್ನು ಕುರಿತಾದ್ದು. ಆಚರಿಸಲು\nಆರಾಮ. ಅಳಿವಿಲ್ಲದ್ದು.\n\nಕೃಷ್ಣ ತಾನು ಮುಂದೆ ಉಪದೇಶ ಮಾಡಲಿರುವ ಅಧ್ಯಾತ್ಮ ವಿಜ್ಞಾನದ ಬಗ್ಗೆ ಹೇಳುತ್ತಾ ಹೇಳುತ್ತಾನೆ: “ಇದು\nವಿದ್ಯೆಗಳಲ್ಲೆಲ್ಲಾ ಪ್ರಧಾನ ವಿದ್ಯೆ; ಅತ್ಯಂತ ರಹಸ್ಯವಾದ ಮತ್ತು ಪರಮ ಪವಿತ್ರವಾದ ವಿದ್ಯೆ” ಎಂದು. 'ಪ್ರತ್ಯಕ್ಷ'\nಶಬ್ದವಾಚ್ಯನಾದ(ಇಂದ್ರಿಯ ನಿಯಾಮಕನಾಗಿರುವ ) ಭಗವಂತನನ್ನು ಪ್ರತ್ಯಕ್ಷ ತೋರಿಸುವಂತಹ; ಜಗತ್ತಿನ\nಧಾರಕ ಶಕ್ತಿಯಾದ ಭಗವಂತನನ್ನು ನೇರ ವಿಷಯೀಕರಿಸುವ, ಸಾಕ್ಷಾತ್‌ ಭಗವದ್‌ ವಿಷಯಕವಾದ ವಿದ್ಯೆ. ಈ\nವಿದ್ಯೆಯನ್ನು ತಿಳಿದು ಭಗವಂತನನ್ನು ಒಲಿಸಿಕೊಳ್ಳುವುದು ಬಹಳ ಸುಲಭ. ಏಕೆಂದರೆ ಭಗವಂತನಿಗೆ ಅತ್ಯಂತ\nಪ್ರಿಯವಾದದ್ದು ಜ್ಞಾನ. ಭಗವಂತ ಜ್ಞಾನಕ್ಕೆ ಒಲಿದಷ್ಟು ಸುಲಭವಾಗಿ ಯಾವ ದಾರಿಗೂ ಒಲಿಯುವುದಿಲ್ಲ. “ಇದು\nಅಳಿವಿರದ ದಾರಿ” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಆದ್ದರಿಂದ ಜ್ಞಾನದ ದಾರಿ ಎಂದೂ ವ್ಯರ್ಥವಲ್ಲ.",
  "9.3": "ಅಶ್ರದ್ದಧಾನಾಃ ಪುರುಷಾಃ ಧರ್ಮಸ್ಯ ಅಸ್ಯ ಪರಂತಪ ।\nಅಪ್ರಾಪ್ಯ ಮಾಮ್‌ ನಿವರ್ತಂತೇ ಮೃತ್ಯು ಸಂಸಾರ ವರ್ಮ್ಮನಿ -- ಪರಂತಪಾ, ಈ ನಡೆಯ ಬಗೆಗೆ ನಂಬಿಕೆಯಿಡದ\nಮಂದಿ ನನ್ನನ್ನು ಪಡೆಯದೆ ಸಾವಿನ ಸುಳಿಯಾದ ಬಾಳ ದಾರಿಯಲ್ಲಿ ಜಾರಿಬೀಳುತ್ತಾರೆ.\n\nಹಿಂದೆ ಅಸೂಯೆ ಬಗ್ಗೆ ಹೇಳಿದ್ದ ಕೃಷ್ಣ ಇಲ್ಲಿ ಇನ್ನೊಂದು ಅತೀ ಮುಖ್ಯವಾದ ಗುಣದ ಬಗ್ಗೆ ಹೇಳುತ್ತಾನೆ- ಅದೇ\n'ಶ್ರದ್ಧೆ'. ಯಾರಿಗೆ ಶ್ರದ್ಧೆ ಇಲ್ಲವೋ ಅವರಿಗೆ ಏನನ್ನು ಹೇಳಿಯೂ ಉಪಯೋಗವಿಲ್ಲ. ನಮಗೆ ಯಾವುದರ ಮೇಲೆ\nಶ್ರದ್ಧೆ ಇಲ್ಲವೋ ಅದನ್ನು ನಮ್ಮ ಮನಸ್ಸು ಸ್ವೀಕರಿಸುವುದೇ ಇಲ್ಲ. ಒಂದು ವಿಷಯವನ್ನು ನಾವು ಗ್ರಹಣ\nಮಾಡಬೇಕಾದರೆ ನಮಗೆ ಆ ವಿಷಯದಲ್ಲಿ ಶ್ರದ್ಧೆ ಇರಬೇಕು. “ನನಗೆ ಗೊತ್ತಿಲ್ಲದ ವಿಷಯಗಳು ಇರಲು ಸಾಧ್ಯ,\nಏಕೆಂದರೆ ನನಗೆ ಗೊತ್ತಿಲ್ಲದೇ ಇರುವ ಬಹಳ ಸಂಗತಿಗಳಿವೆ” -ಎಂದು ತಿಳಿಯುವುದು ಶ್ರದ್ಧೆಯ ಮೊದಲ\nಮೆಟ್ಟಿಲು. (I must know that I do not know). ನಮ್ಮ ಅಜ್ಞಾನದ ಅರಿವು ನಮಗಿರಬೇಕು. ಆಗ ಗೊತ್ತಿಲ್ಲದ್ದನ್ನು\nಗೊತ್ತು ಮಾಡಿಕೊಳ್ಳುವ ಶ್ರದ್ಧೆ ಬರುತ್ತದೆ. ಮೊದಲು ಗೊತ್ತಿಲ್ಲ ಅನ್ನುವುದರ ಬಗ್ಗೆ ನಮಗೆ ಗೊತ್ತಿರಬೇಕು; ಆಮೇಲೆ\nನಮಗೆ ಗೊತ್ತಿಲ್ಲದೇ ಇರುವ ವಿಷಯ ಸತ್ಯವಾಗಿರುವ ಸಾಧ್ಯತೆ ಇದೆ ಎನ್ನುವ ಸಾಧ್ಯತೆಯ ಅರಿವು ಬೇಕು;\nಅದನ್ನು ತಿಳಿಯುವ ಶ್ರದ್ಧೆ ಬೇಕು. ಹೀಗೆ ತಿಳಿಯುತ್ತಾ, ಗೊತ್ತಿಲ್ಲದ ವಸ್ತು ಇದೆ ಎನ್ನುವ ಸತ್ಯ ತಿಳಿಯುತ್ತದೆ.\n\nಜ್ಞಾನದ ದಾರಿಯಲ್ಲಿ ಸಾಗುವ ಸಾಧಕನಿಗೆ ಮೂಲಭೂತವಾಗಿ ನಂಬಿಕೆ ಬೇಕು. ನಂಬದವನ ಮುಂದೆ ಏನು\nಹೇಳಿಯೂ ಪ್ರಯೋಜನವಿಲ್ಲ. ಇದನ್ನೇ ಇಲ್ಲಿ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಯಾರಿಗೆ ಶ್ರದ್ಧೆ ಇಲ್ಲವೋ ಅಂತವರ ಪಾಲಿಗೆ\nಸತ್ಯ ಇಲ್ಲ” ಎಂದು. ಜಗತ್ತಿನ ಧಾರಕನಾದ ಭಗವಂತನ ಬಗೆಗೆ ನಂಬಿಕೆ ಇಲ್ಲದವರು ಭಗವಂತನನ್ನು\nಸೇರುವುದಿಲ್ಲ. “ಅಂತವರು ಆತ್ಮ ನಾಶವಾದ ತಮಸ್ಸ ನ್ನು ಸೇರುತ್ತಾರೆ ಅಥವಾ ಸಂಸಾರದ ಸುಳಿಯಲ್ಲಿ\nಸುತ್ತುತ್ತಿರುತ್ತಾರೆ” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.\n\nಈ ಶ್ಲೋಕದಲ್ಲಿ ಪರಂತಪ ಎನ್ನುವ ವಿಶೇಷಣವನ್ನು ಬಳಸಲಾಗಿದೆ. ಇದರ ಮೇಲ್ನೋಟದ ಅರ್ಥ ಶತ್ರುಗಳನ್ನು\nಸುಡುವ ಶೂರ ಎಂದು. ನಮ್ಮ ಜೀವನ ಯುದ್ಧದಲ್ಲಿ ನಮ್ಮ ಶತ್ರುಗಳೆಂದರೆ ನಮ್ಮೊಳಗೆ ಇರುವ ಅಜ್ಞಾನ, ಮೋಹ,\nಕಾಮ, ಕ್ರೋಧ, ಇತ್ಯಾದಿಗಳು. ಪ್ರತಿಯೊಬ್ಬ ಸಾಧಕ ಕೂಡಾ ಪರತತ್ವದಲ್ಲಿ ಶ್ರದ್ಧೆಯನ್ನಿಟ್ಟು ಇಂತಹ ಶತ್ರುಗಳನ್ನು\nಸುಡುವ ಬೆಂಕಿಯಾಗಬೇಕು, ಸುಟ್ಟು ಬೆಳಗುವ ಪರಂತಪನಾಗಬೇಕು.",
  "9.4": "ಮಯಾ ತತಮ್‌ ಇದಂ ಸರ್ವಂ ಜಗತ್‌ ಅವ್ಯಕ್ತ ಮೂರ್ತಿನಾ |\nಮತ್‌ ಸ್ಥಾನಿ ಸರ್ವಭೂತಾನಿ ನ ಚ ಅಹಂ ತೇಷು ಅವಸ್ಥಿತಃ -ಈ ಎಲ್ಲಾ ಜಗತ್ತು ಮೈದೋರದ ನನ್ನಿಂದ\nತುಂಬಿದೆ. ಇಲ್ಲಿ ಇರುವುದೆಲ್ಲವೂ ನನ್ನಲ್ಲಿ ನೆಲೆಸಿವೆ. ನಾನು ಅವುಗಳ ನೆರವಿನಲ್ಲಿಲ್ಲ.\n\nಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ನಾನು ಇಡೀ ಜಗತ್ತಿನಲ್ಲಿ ತುಂಬಿರುವ ಅವ್ಯಕ್ತಮೂರ್ತಿ” ಎಂದು. ಇಲ್ಲಿ ಬಳಸಿರುವ\nಅವ್ಯಕ್ತಮೂರ್ತಿ ಎನ್ನುವ ಪದದಲ್ಲಿ ಅವ್ಯಕ್ತ ಮತ್ತು ಮೂರ್ತಿ ಎನ್ನುವುದು ಪರಸ್ಪರ ವಿರುದ್ಧ ಪದಗಳು. ಅವ್ಯಕ್ತ\nಎಂದರೆ ಕಾಣದ್ದು, ಆಕಾರವಿಲ್ಲದ್ದು. ಮೂರ್ತಿ ಎಂದರೆ ಆಕೃತಿ ಮತ್ತು ರೂಪ. ಭಗವಂತ ಆಕಾಶದಂತೆ ಎಲ್ಲೆಡೆ\nವ್ಯಾಪಿಸಿರುವ ಅವ್ಯಕ್ತ ಆದರೆ ಆತ ಜ್ಞಾನಾನಂದಮಯನಾಗಿ ಎಲ್ಲರೊಳಗೆ ತುಂಬಿರುವ ಮೂರ್ತಿ. ಒಂದೊಂದು\nವಸ್ತುವಿನಲ್ಲೂ ಒಂದೊಂದು ರೂಪದಲ್ಲಿ ತುಂಬಿರುವ ಅನಂತ ರೂಪಗಳುಳ್ಳವ ಆ ಭಗವಂತ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ:\n“ಪ್ರತಿಯೊಂದು ವಸ್ತುವಿಗೂ ನಾನು ಆಧಾರ, ಈ ಇಡೀ ಪ್ರಪಂಚ ನನ್ನನ್ನು ಅವಲಂಬಿಸಿಕೊಂಡಿದೆ. ಆದರೆ ನಾನು\nನಿರಾಲಂಬನಾಗಿ ಎಲ್ಲೆಡೆ ತುಂಬಿದ್ದೇನೆ”. ಎಂದು.\n",
  "9.5": "ನ ಚ ಮತ್‌ ಸ್ಥಾನಿ ಭೂತಾನಿ ಪಶ್ಯ ಮೇ ಯೋಗಮ್‌ ಐಶ್ವರಮ್‌ |\n\nಭೂತಭೃತ್‌ ನ ಚ ಭೂತಸ್ಥಃ ಮಮ ಆತ್ಮಾ ಭೂತಭಾವನಃ - ನನ್ನಲ್ಲಿ ಎಲ್ಲಾ ಉಂಟು; ನನಗಿಲ್ಲ ಯಾವುದರ\nಅಂಟು. ನೋಡು-ಮಿಗಿಲಾದ ನನ್ನ ಮಹಿಮೆಯನ್ನು. ನನ್ನ ರೂಪ ಇವುಗಳಿಗೆ ರೂಪು ಕೊಟ್ಟಿದೆ. ಹೊತ್ತು ಸಲಹಿದೆ.\nಆದರೂ ಇವುಗಳಲ್ಲಿಲ್ಲ.\n\nಹಿಂದಿನ ಮತ್ತು ಈ ಶ್ಲೋಕದಲ್ಲಿ ಕೃಷ್ಣ ಹೇಳುವ ವಿಚಾರವನ್ನು ನಾವು ಗಮನವಿಟ್ಟು ನೋಡಬೇಕು. ಮೇಲ್ನೋಟಕ್ಕೆ\nಇವು ಒಂದೊಕ್ಕೊಂದು ವಿರುದ್ಧವಾಗಿರುವ ಒಗಟಿನ ಹೇಳಿಕೆಯಂತೆ ಕಾಣುತ್ತದೆ. ಕೃಷ್ಣ ಹೇಳುವ ಮಾತು ಹೀಗಿದೆ\n\"ನನ್ನ ಸಾಮರ್ಥ್ಯವನ್ನು ತಿಳಿ, ನಾನು ಎಲ್ಲವುದರಲ್ಲೂ ಇದ್ದೇನೆ-ಆದರೆ ಯಾವುದರಲ್ಲೂ ಇಲ್ಲ. ಎಲ್ಲವೂ ನನ್ನ ಲ್ಲಿದೆ\nಆದರೆ ಯಾವುದೂ ನನ್ನಲ್ಲಿಲ್ಲ. ಇದು ಭಗವಂತನ ಅಚಿಂತ್ಯ ಶಕ್ತಿಯ ಅನುಸಂಧಾನ. ಭಾಗವತದಲ್ಲಿ\nಹೇಳುವಂತೆ “ನಾವು ಯಾವುದನ್ನು ಪ್ರಪಂಚದಲ್ಲಿ ವಿರೋಧಾತ್ಮಕ(Contradictory) ಎನ್ನುತ್ತೇವೋ ಅವು ಶುಭ\nಧರ್ಮವಾದಲ್ಲಿ ಭಗವಂತನಲ್ಲಿ ಅನ್ವಯವಾಗುತ್ತವೆ'. ಈ ವಿರುದ್ಧವಾದ ಧರ್ಮವನ್ನು ಹೇಳುವುದರ ಮೂಲಕ ಇಲ್ಲಿ\nಭಗವಂತ ಏನನ್ನು ತಿಳಿಸುತ್ತಿದ್ದಾನೆ.. ಎಂದರೆ. - ಎಲ್ಲವೂ ನನ್ನಲ್ಲಿದೆ. ಆದರೆ. ಯಾವ\nಮಮಕಾರವೂ ನನಗಿಲ್ಲ”. ಅಂದರೆ ಇದು ಭಗವಂತನ ನಿರ್ಲಿಪ್ತತೆಯನ್ನು ಸೂಚಿಸುತ್ತದೆ. ಆತ\nಯಾವುದನ್ನೂ ಅಂಟಿಸಿಕೊಳ್ಳುವುದಿಲ್ಲ. ಆತ ಯಾವುದನ್ನೂ ಆಶ್ರಯಿಸಿಕೊಂಡಿಲ್ಲ ಮತ್ತು ಯಾವುದರ ಲೇಪವೂ\nಆತನಿಗಿಲ್ಲ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಇದು ನನ್ನ ಈಶ್ವರೀಯ ಶಕ್ತಿ” ಎಂದು. ಇದು ಭಗವಂತನ ಸರ್ವಸಮರ್ಥತೆ.\n\nಈ ವಿಚಾರವನ್ನು ಕೃಷ್ಣ ಇನ್ನೊಮ್ಮೆ ಸಂಕ್ಷಿಪ್ತ(Crisp)ವಾಗಿ “ಭೂತಭೃತ್‌ ನಚ ಭೂತಸ್ಥಃ” ಎಂದು ವಿವರಿಸುತ್ತಾನೆ.\nಇಲ್ಲಿ 'ನಚ' ಎನ್ನುವ ಪದ ಹೊಸ್ತಿಲಲ್ಲಿ ಇಟ್ಟ ದೀಪದಂತೆ ಎರಡು ಪದಗಳ ನಡುವೆ ಬಳಕೆಯಾಗಿದೆ. ಇದರರ್ಥ\nಹೀಗೆ: “ನಾನು ಭೂತಭೃತ್‌-ಎಲ್ಲಾ ಜೀವಜಾತಗಳನ್ನು ಧರಿಸಿದ್ದೇನೆ ಮತ್ತು ನಚಭೂತಭೃತ್‌-ಏನನ್ನೂ ಧರಿಸಿಲ್ಲ;\nನಾನು ಭೂತಸ್ಥ-ಎಲ್ಲಾ ಜೀವಜಾತಗಳೂ ನನ್ನಲ್ಲಿವೆ ಮತ್ತು ನಾನು ನಚಭೂತಸ್ಥ-ಯಾವುದರಲ್ಲೂ ನಾನಿಲ್ಲ”.\n\nಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಮಮ ಆತ್ಮಾ ಭೂತಭಾವನಃ” ಎಂದು. ಅಂದರೆ ಈ ಜಗತ್ತಿನ ಸೃಷ್ಟಿ-ಸ್ಥಿತಿ-ಸಂಹಾರ-\nನಿಯಮನ-ಜ್ಞಾನ-ಅಜ್ಞಾನ-ಬಂಧ-ಮೋಕ್ಷ ಎಲ್ಲವೂ ಭಗವಂತನಿಂದ. ಆತ ಜ್ಞಾನಾನಂದ ಸ್ವರೂಪ. ಭಗವಂತ\nಬೇರೆ ಆತನ ದೇಹ ಬೇರೆ ಅಲ್ಲ; ಆತನ ಗುಣ ಕ್ರಿಯೆಗಳು ಬೇರೆ ಅಲ್ಲ. ಅವೆಲ್ಲವೂ ಅಖಂಡ. ಇದನ್ನು\nಪಾಂಚಭೌತಿಕ ಮತ್ತು ತ್ರೈಗುಣ್ಯದ ಪರಿದಿಯಲ್ಲಿ ನಾವು ಕಲ್ಪಿಸಲು ಸಾಧ್ಯವಿಲ್ಲ.\n\nಭಗವಂತ ಹೇಗೆ ಎಲ್ಲಾ ಕಡೆ ತುಂಬಿದ್ದಾನೆ ಎನ್ನುವುದನ್ನು ಕೃಷ್ಣ ಒಂದು ದೃಷ್ಟಾಂತದ ಮೂಲಕ ಮುಂದಿನ\nಶ್ಲೋಕದಲ್ಲಿ ವಿವರಿಸುತ್ತಾನೆ.",
  "9.6": "ಯಥಾ ಆಕಾಶಸ್ಥಿತಃ ನಿತ್ಯಮ್‌ ವಾಯುಃ ಸರ್ವತ್ರ ಗಃ ಮಹಾನ್‌।\nತಥಾ ಸರ್ವಾಣಿ ಭೂತಾನಿ ಮತ್‌ ಸ್ಥಾನಿ ಇತಿ ಉಪಧಾರಯ -ಎಲ್ದೆಡೆ ಹಿಗ್ಗಿ ತುಂಬಿರುವ ಗಾಳಿ ಎಂದೆಂದೂ\nಆಗಸದಲ್ಲಿರುವಂತೆ ಜಗದ ಎಲ್ಲಾ ಇರುವಿಕೆಗಳೂ ನನ್ನಲ್ಲಿವೆ. ಎಂದು ಮನಗಾಣು.\n\nಗಾಳಿ ಎಲ್ಲಾ ಕಡೆ ಇದೆ. ಅದು ಒಳಗೂ ಇದೆ, ಹೊರಗೂ ಇದೆ. ಗಾಳಿ ನಮಗೆ ಕಾಣುವುದಿಲ್ಲ. ಗಾಳಿ ಈ ಆಕಾಶದಲ್ಲಿ\nತುಂಬಿದೆ. ಹೀಗೆ ಭಗವಂತ ನಮ್ಮ ಒಳಗೂ ಹೊರಗೂ ತುಂಬಿ ನಿಂತಿದ್ದಾನೆ. ಆದರೆ ಯಾವುದರ ಲೇಪವೂ\nಆತನಿಗಿಲ್ಲ. ಈ ಜಗತ್ತಿನ ಸರ್ವ ಇರುವಿಕೆಯೂ ಭಗವಂತನಲ್ಲಿದೆ.",
  "9.7": "ಸರ್ವಭೂತಾನಿ ಕೌಂತೇಯ ಪ್ರಕೃತಿಂ ಯಾಂತಿ ಮಾಮಿಕಾಮ್‌ ।\nಕಲ್ಪಕ್ಷಯೇ ಪುನಃ ತಾನಿ ಕಲ್ಪ ಆದೌ ವಿಸೃಜಾಮಿ ಅಹಮ್‌ – ಸೃಷ್ಟಿಯ ಕೊನೆಯಲ್ಲಿ ಎಲ್ಲಾ ವಸ್ತುಗಳೂ ನನ್ನದೇ ಆದ ಮೂಲ ಪ್ರಕೃತಿಯನ್ನು ಸೇರುತ್ತವೆ. ಸೃಷ್ಟಿಯ ಮೊದಲಲ್ಲಿ ಮರಳಿ ಅವನ್ನು ನಾನು ನಿರ್ಮಿಸುತ್ತೇನೆ.\n\nಸೃಷ್ಟಿಯಾಗಿ 31,104 ಸಾವಿರ ಕೋಟಿ ವರ್ಷಗಳ ನಂತರ ಮಹಾಪ್ರಳಯ. ಇದು ಚತುರ್ಮುಖ ಬ್ರಹ್ಮನ ನೂರು ವರ್ಷ. ಇದನ್ನು ಕಲ್ಪಕ್ಷಯ ಎನ್ನುತ್ತಾರೆ. ಈ ಮಹಾಪ್ರಳಯದಲ್ಲಿ ಸತ್ಯಲೋಕದಿಂದ ಹಿಡಿದು ಪ್ರತಿಯೊಂದೂ ತನ್ನ ಸ್ಥೂಲ ರೂಪವನ್ನು ಕಳೆದುಕೊಂಡು ಸೂಕ್ಷ್ಮ ರೂಪದಲ್ಲಿ ಭಗವಂತನ ಅಧೀನವಾದ ಪ್ರಕೃತಿಯನ್ನು ಸೇರುತ್ತವೆ. ಎಲ್ಲಾ ಜೀವ ಜಾತಗಳೂ ಕೂಡಾ ತಮ್ಮ ಸ್ಥೂಲರೂಪವನ್ನು ಕಳೆದುಕೊಂಡು ಭಗವಂತನ ಉದರವನ್ನು ಸೇರುತ್ತದೆ. ಮತ್ತೆ 31,104 ಸಾವಿರ ಕೋಟಿ ವರ್ಷ ಪ್ರಳಯಕಾಲ. ನಂತರ ಮರಳಿ ಈ ಸೃಷ್ಟಿ ನಿರ್ಮಾಣವಾಗುತ್ತದೆ. ಅಂದರೆ ಮರಳಿ ಸೂಕ್ಷ್ಮರೂಪದಿಂದ ಸ್ಥೂಲರೂಪವನ್ನು ಪಡೆಯುತ್ತದೆ.",
  "9.8": "ಪ್ರಕೃತಿಮ್‌ ಸ್ವಾಮ್‌ ಅವಷ್ಟಭ್ಯ ವಿಸೃಜಾಮಿ ಪುನಃಪುನಃ ।\nಭೂತ ಗ್ರಾಮಮ್‌ ಇಮಮ್‌ ಕೃತ್ಸ್ನಮ್‌ ಅವಶಮ್‌ ಪ್ರಕೃತೇಃ ವಶಾತ್‌ - ಪ್ರಕೃತಿಯ ನಿಯತಿಗೊಳಪಟ್ಟು\nಪರತಂತ್ರವಾದ [ನನ್ನಂಕೆಯಲ್ಲಿರುವ] ಈ ಇಡಿಯ ವಿಶ್ವವನ್ನು ನನ್ನದೇ ಆದ ಪ್ರಕೃತಿಯನ್ನು ಬಳಸಿ ಮತ್ತೆ ಮತ್ತೆ\nನಿರ್ಮಿಸುತ್ತೇನೆ.\n\nಪ್ರಳಯ ಕಾಲದಲ್ಲಿ ಸೂಕ್ಷ್ಮರೂಪದಲ್ಲಿ ಭಗವಂತನನ್ನು ಸೇರಿದ ಜಡ ಮತ್ತು ಜೀವವನ್ನು ಭಗವಂತ ತನ್ನ\nಅಧೀನವಾದ ಪ್ರಕೃತಿಯನ್ನು ಬಳಸಿ ಮತ್ತೆ ಸೃಷ್ಟಿ ಮಾಡುತ್ತಾನೆ. ಭಗವಂತನ ಈ ಸೃಷ್ಟಿ ಮತ್ತು ಸಂಹಾರಚಕ್ರ\nನಿರಂತರ. ಇಂತಹ ಅನಂತ ಬ್ರಹ್ಮಾಂಡಗಳು ಹಿಂದೆ ನಿರ್ಮಾಣವಾಗಿ ಸಂಹಾರವಾಗಿವೆ ಮತ್ತು ಇನ್ನೂ ಅನಂತ\n\nಕಾಲದಲ್ಲೂ ಇದು ಮುಂದುವರಿಯುತ್ತದೆ. ಈ ಕಾರಣಕ್ಕಾಗಿ ಭಗವಂತನನ್ನು ಅನಂತ ಕೋಟಿ ಬ್ರಹ್ಮಾಂಡನಾಯಕ\nಎಂದು ಕರೆಯುತ್ತಾರೆ.(ಈ ಬಗ್ಗೆ ವಿವರವಾಗಿ ನಾವು ಏಳನೇ ಅಧ್ಯಾಯದಲ್ಲೇ ಚರ್ಚಿಸಿದ್ದೇವೆ).\n\nಹೀಗೆ ನಿರಂತರ ಸೃಷ್ಟಿ-ಸಂಹಾರ ಮಾಡುವ ಭಗವಂತನಿಗೆ ಕರ್ಮ ಅಂಟುವುದಿಲ್ಲವೇ? ಮುಂದಿನ ಶ್ಲೋಕಗಳಲ್ಲಿ\nನೋಡೋಣ:\n",
  "9.9": "ನ ಚ ಮಾಮ್‌ ತಾನಿ ಕರ್ಮಾಣಿ ನಿಬಧ್ದನ್ತಿ ಧನಂಜಯ ।\n\nಉದಾಸೀನವತ್‌ ಆಸೀನಮ್‌ ಅಸಕ್ತಮ್‌ ತೇಷು. ಕರ್ಮಸು -ಧನಂಜಯಾ, ನಾನು ಮಾಡಿಯೂ\nಮಾಡದವನಂತೆ ಇದ್ದುಬಿಡುತ್ತೇನೆ. ಆ ಕರ್ಮಗಳಲ್ಲಿ ನನಗೆ ನಂಟಿಲ್ಲ. ಆದ್ದರಿಂದ ಆ ಕರ್ಮಗಳು ನನ್ನನ್ನು ಕಟ್ಟಿ\nಹಾಕಲಾರವು.\n\nಭಗವಂತ ನಿರ್ಲಿಪ್ತ, ಆತ ಕರ್ಮ ಮಾಡುವುದು ಆತನಿಗೋಸ್ಕರ ಅಲ್ಲ. ಸ್ವತಂತ್ರನಾದ ಭಗವಂತನನ್ನು ಎಂದೂ\nಯಾವ ಕರ್ಮವೂ ಕಟ್ಟಿ ಹಾಕಲಾರವು.(ಒಂದು ವೇಳೆ ಹಾಗೆ ಕಟ್ಟಿ ಹಾಕುವುದಾದರೆ ಭಗವಂತ ಸ್ವತಂತ್ರ\nಎನಿಸುವುದಿಲ್ಲ? “ನಾನು ನನಗೋಸ್ಕರ ಏನನ್ನೂ ಮಾಡುವುದಿಲ್ಲ ಮತ್ತು ಕರ್ಮ ನನಗೆ ಅಂಟುವುದಿಲ್ಲ” ಎಂದು\nಸ್ಪಷ್ಟವಾಗಿ ಹೇಳುತ್ತಾನೆ ಕೃಷ್ಣ.\n\nಈ ಶ್ಲೋಕದಲ್ಲಿ ಧನಂಜಯ ಎನ್ನುವ ವಿಶೇಷಣ ಬಳಕೆಯಾಗಿದೆ. ವ್ಯವಹಾರಿಕವಾಗಿ ಈ ನಾಮವನ್ನು ನೋಡಿದರೆ\n'ಜನರಿಂದ ಹಣವನ್ನು ದೋಚಿ ದುಷ್ಟ ರಾಜ್ಯಭಾರ ಮಾಡುವ ಶತ್ರು ರಾಜರನ್ನು ಸೋಲಿಸಿ, ಆ ಸಂಪತ್ತನ್ನು\nಜಯಿಸಿ, ಅದನ್ನು ಪ್ರಜೆಗಳಿಗಾಗಿ ಸದುಪಯೋಗ ಮಾಡುವವ ಧನಂಜಯ'. [ತನ್ನ ಸ್ವಾರ್ಥಕ್ಕಾಗಿ ಇನ್ನೊಬ್ಬರ\nಮೇಲೆ ದಾಳಿಮಾಡಿ ಹಣ ಗಳಿಸುವವ “ದರೋಡೆಕೋರ' ಎನಿಸುತ್ತಾನೆ ಹೊರತು ಧನಂಜಯ ಎನಿಸುವುದಿಲ್ಲ.\nಮಹಾಭಾರತದಲ್ಲಿ ಏಕಲವ್ಯ ಈ ಎರಡನೇ ಗುಂಪಿಗೆ ಸೇರಿದವನಾಗಿದ್ದ. ಆದ್ದರಿಂದ ಆತನ ಬೆರಳನ್ನು\nಕತ್ತರಿಸಲಾಯಿತು ಮತ್ತು ಕೃಷ್ಣ ಸ್ವತಃ ಆತನನ್ನು ಸಂಹಾರ ಮಾಡಿದ್ದ.] ಆಧ್ಯಾತ್ಮಿಕವಾಗಿ ನಿಜವಾದ ಧನ ಎಂದರೆ\nಭಗವಂತ. ಅಂತಹ ಭಗವಂತನ ಜ್ಞಾನವನ್ನು ಪಡೆದವ ಧನಂಜಯ. ನಾವೆಲ್ಲರೂ ಅರ್ಜುನನಂತೆ ಭಗವಂತನ\nಜ್ಞಾನವನ್ನು ಪಡೆದು ಧನಂಜಯರಾದಾಗ ಮಾತ್ರ ಮೋಕ್ಷವನ್ನು ಪಡೆಯಲು ಸಾಧ್ಯ.",
  "9.10": "ಮಯಾ ಅಧ್ಯಕ್ಷೇಣ ಪ್ರಕೃತಿಃ ಸೂಯತೇ ಸ ಚರ ಅಚರಮ್‌।\n\nಹೇತುನಾ ಅನೇನ ಕೌಂತೇಯ ಜಗತ್‌ ವಿಪರಿವರ್ತತೇ-ಸಾಕ್ಷಿಯಾಗಿ ನಿಂತ ನನ್ನಿಂದಲೇ ಜೀವ-ಜಡಗಳನ್ನು\nಬೆಸೆದು ಪ್ರಕೃತಿ ಹಡೆಯುತ್ತದೆ. ಕೌಂತೇಯಾ, ಈ ಕಾರಣದಿಂದಲೇ ಜಗತ್ತು ಬದಲಾಗುತ್ತಾ ಸುತ್ತುತ್ತಿದೆ.\n\nಜಗತ್ತನ್ನು ಸೃಷ್ಟಿ ಮಾಡಲು ಬೇಕಾದ ಮೂಲದ್ರವ್ಯ ಜಡಪ್ರಕೃತಿ ಮತ್ತು ಅದಕ್ಕೆ ಆಕಾರ ಕೊಡುವುದು\nಜಡಪ್ರಕೃತಿಯ ಮಾನಿನಿಯಾದ ಚೇತನ ಪ್ರಕೃತಿ ಲಕ್ಷ್ಮಿ. ಭಗವಂತ ಇಡೀ ಸೃಷ್ಟಿಯ ಅಧ್ಯಕ್ಷನಾಗಿ ನಿಂತು,\nಕ್ರಿಯೆಯ ಹಿಂದಿನ ಶಕ್ತಿಯಾಗಿ, ಜಡ ಮತ್ತು ಚೇತನಪ್ರಕೃತಿಯ ಮೂಲಕ ಈ ಸೃಷ್ಟಿ ನಿರ್ಮಾಣ ಮಾಡುತ್ತಾನೆ.\nಪ್ರಪಂಚದಲ್ಲಿರುವ ಪ್ರತಿಯೊಂದು ವಸ್ತುವಿನಲ್ಲೂ ಕೂಡಾ ಒಂದು ವಿಶಿಷ್ಟ ಶಕ್ತಿಯಾಗಿ ಭಗವಂತ ತುಂಬಿದ್ದಾನೆ.",
  "9.11": "ಅವಜಾನಂತಿ ಮಾಮ್‌ ಮೂಢಾಃ ಮಾನುಷೀಂ ತನುಮ್‌ ಆಶ್ರಿತಮ್‌ |\n\nಪರಮ್‌ ಭಾವಮ್‌ ಅಜಾನಂತಃ ಮಮ ಭೂತಮಹೇಶ್ವರಮ್‌-ಮನುಷ್ಯರಂತೆ ಕಾಣಿಸಿಕೊಂಡು ಮೈದಾಳಿದ\nನನ್ನನ್ನು ಮನುಷ್ಯನೆಂದೇ ಬಗೆದು ಕಡೆಗಾಣಿಸುತ್ತಾರೆ-ಎಂದೆಂದೂ ಎಲ್ಲೆಡೆಯೂ ಇರುವ ಹಿರಿದಕ್ಕೂ ಹಿರಿದಾದ\nನನ್ನ ಹಿರಿಮೆಯನ್ನರಿಯದ ತಿಳಿಗೇಡಿಗಳು.\n\nಈ ಶ್ಲೋಕದಲ್ಲಿ ಭಗವಂತ ತನ್ನ ಸ್ವರೂಪದ ಬಗ್ಗೆ ಇನ್ಯಾರೂ ಹೇಳಲಾಗದ ಒಂದು ಸಂಗತಿಯನ್ನು ಹೇಳುತ್ತಾನೆ.\nಭಗವಂತನಿಗೆ ಪಾಂಚಭೌತಿಕ ಶರೀರವಿಲ್ಲ. ಅವತಾರ ರೂಪಿ ಭಗವಂತ ನಮಗೆ ನಮ್ಮಂತೇ ಶರೀರ\nಉಳ್ಳವನಂತೆ ಕಾಣಿಸಿಕೊಳ್ಳುತ್ತಾನೆ ಅಷ್ಟೇ. ಅಲ್ಲಿ ಕಾಣುವ ಶರೀರವನ್ನು ಕಂಡು: ಭಗವಂತನ ಶರೀರ ನಮ್ಮಂತೆ\nನಶ್ಚರವಾದ, ಒಂದು ದಿನ ಬಿದ್ದು ಹೋಗುವ ಶರೀರ ಎಂದು ತಿಳಿಯುವವರು- ಸ್ವಭಾವತಃ ತಾಮಸರು ಅಥವಾ\nತಾಮಸದ ಪ್ರಭಾವಕ್ಕೆ ಒಳಗಾದ ಭಗವಂತನ ಹಿರಿಮೆಯನ್ನರಿಯದ ತಿಳಿಗೇಡಿಗಳು ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.\n\nಇಲ್ಲಿ ಭೂತಮಹೇಶ್ವರ ಎನ್ನುವ ವಿಶೇಷಣ ಬಳಕೆಯಾಗಿದೆ. ಇದು ಭಗವಂತನ ಹಿರಿಮೆಯನ್ನು ಹೇಳುವ ವಿಶೇಷ\nಪದ. ಸಮಷ್ಟಿಯಾಗಿ ಈ ಪದವನ್ನು ನೋಡಿದರೆ: ಭೂತಗಳು ಎಂದರೆ ಸಮಸ್ತ ಜೀವಗಳು. ಅವರಿಗೆ ಈಶರು\nಬ್ರಹ್ಮಾದಿ ದೇವತೆಗಳು(ಭೂತೇಶರು). ಈ ದೇವತೆಗಳಿಗೆ ಮಹತ್ತಾದವಳು ಶ್ರೀಲಕ್ಷ್ಮೀಭೂತಮಹೇಶಳು). ಇಂತಹ\nಲಕ್ಷ್ಮಿಗೆ ವರನಾಗಿರುವ ಭಗವಂತ “ಭೂತಮಹೇಶ್ವರ”. . ಇದೇ ಪದವನ್ನು ಬಿಡಿಸಿ. ನೋಡಿದರೆ\nಭೂತಮಹಾನ್‌- ಈಶ್ವರ : ಅಂದರೆ ಬ್ರಹ್ಮಾದಿ ಸಮಸ್ತ ಭೂತಗಳಿಗೂ ಮಹಾನ್‌ ಆಗಿ ಎಲ್ಲರನ್ನೂ ನಿಯಂತ್ರಿಸುವ\n, ಸರ್ವೋನ್ನತನಾದ- ಸರ್ವಸಮರ್ಥ ಭಗವಂತ. ಇನ್ನೊಂದು ರೀತಿಯಲ್ಲಿ ಭೂತ-ಮಹತ್‌-ಈಶ್ವರ. ಇಲ್ಲಿ ಭೂತ\nಎಂದರೆ: ಉನ್ನತಿಯ ತುತ್ತ ತುದಿಯಲ್ಲಿರುವ, ಹುಟ್ಟು ಸಾವಿಲ್ಲದ ಅನಾಧಿನಿತ್ಯ. ಮಹತ್‌ ಎಂದರೆ: ಕಾಲತಃ ,\nದೇಶತಃ, ಗುಣತಃ ಪರಿಪೂರ್ಣವಾಗಿರುವ ತತ್ತ್ವ. ಈಶ್ವರ ಎಂದರೆ : ಸರ್ವ ಸಮರ್ಥ ಭಗವಂತ. ಹೀಗೆ ಈ\nವಿಶೇಷಣ ಅನೇಕ ರೂಪದಲ್ಲಿ ಭಗವಂತನ ಗುಣವನ್ನು ಸಾರುತ್ತದೆ.\n",
  "9.12": "ಮೋಘ ಆಶಾಃ ಮೋಘಕರ್ಮಾಣಃ ಮೋಘಜ್ಞಾನಾಃ ವಿಚೇತಸಃ ।\n\nರಾಕ್ಷಸೀಮ್‌ ಆಸುರೀಮ್‌ ಚ ಏವ ಪ್ರಕೃತಿಮ್‌ ಮೋಹಿನೀಮ್‌ ಶ್ರಿತಾಃ -ಇವರ ಆಸೆ ಈಡೇರದು. ಕರ್ಮಗಳು\nಫಲಿಸವು. ತಿಳಿವು ಮಾಯವಾಗುವುದು. ಅವರು ಬಗೆಗೇಡಿಗಳು; ಮರುಳುಗೊಳಿಸುವ, ರಕ್ಕಸರ -ಅಸುರರ\nತಾಮಸ ಸ್ವಭಾವಕ್ಕೆ ಒಳಗಾದವರು.\n\n“ಭಗವಂತ ಜ್ಞಾನಾನಂದ ಸ್ವರೂಪ, ಆತನಿಗೆ ಪಾಂಚಭೌತಿಕ ಶರೀರ ಇಲ್ಲ' ಎನ್ನುವ ವಿಚಾರವನ್ನು ಕೃಷ್ಣ ಇಲ್ಲಿ\nಒತ್ತು ಕೊಟ್ಟು ಹೇಳುತ್ತಾನೆ. “ದೇವರಿಗೆ ನಮ್ಮಂತೆ ಪಾಂಚಭೌತಿಕ ಶರೀರ ಇದೆ-ಅನ್ನುವ ಚಿಂತನೆಯೇ ಪಾತಕದ\nದಾರಿ” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಏಕೆಂದರೆ ಹಾಗೆ ಚಿಂತನೆ ಮಾಡುವವರು ಸಾತ್ವಿಕರಾಗಿರುವುದಿಲ್ಲ. ಅವರು ಎಂದೂ\nಭಗವದ್‌ ಭಕ್ತರಾಗಿರುವುದಿಲ್ಲ. ಹೀಗೆ ಚಿಂತನೆ ಮಾಡುವವರ ಅಧ್ಯಾತ್ಮ ಸಾಧನೆಯ ಎಲ್ಲಾ ಆಸೆಗಳೂ ಕಮರಿ\nಹೋಗುತ್ತವೆ. ಭಗವಂತನನ್ನು ನಶ್ವರ ಎಂದು ಹೇಳುವವರನ್ನು ದೇವತೆಗಳು ಎಂದೂ ಪ್ರೀತಿಸುವುದಿಲ್ಲ. ಅವರು\nಮಾಡುವ ಯಜ್ಞ-ಯಾಗಾದಿಗಳು ವ್ಯರ್ಥ. ಒಟ್ಟಿನಲ್ಲಿ ಅಧ್ಯಾತ್ಮ ಸಾಧನೆಯಲ್ಲಿ ಪಾರತ್ರಿಕವಾಗಿ ಅವರ ಯಾವ\nಆಸೆಯೂ ನೆರವೇರುವುದಿಲ್ಲ.\n\nಸಾತ್ವಿಕ ಚಿಂತನೆ ಇಲ್ಲದವರು ಅಥವಾ ತಾಮಸ ಪ್ರಭಾವಕ್ಕೊಳಗಾದವರು ಭಗವಂತನನ್ನು ಈ ರೀತಿ ದೋಷ\nಚಿಂತನೆ. ಮಾಡುತ್ತಾರೆ. ಅವರಿಗೆ ಚಿಂತನಾ ಶಕ್ತಿ ಇರುವುದಿಲ್ಲ. ಇವರು ಯಾವ ಶಾಸ್ತ್ರ ಓದಿಯೂ\nಉಪಯೋಗವಿಲ್ಲ. ಅವರ ಮನಸ್ಸು ಅಧ್ಯಾತ್ಮವನ್ನು ಗ್ರಹಿಸುವುದಿಲ್ಲ. “ಇಂತವರು ರಾಕ್ಷಸರು ಅಥವಾ\nಅಸುರರಾಗಿರುತ್ತಾರೆ” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ರಾಕ್ಷಸರು ಎಂದರೆ ಸ್ವಭಾವತಃ ತಾಮಸರು; ಅಸುರರು ಎಂದರೆ\nರಾಜಸರು-ಇಂದ್ರಿಯ ಭೋಗದಲ್ಲೇ ಪುರುಷಾರ್ಥ ಕಾಣುವವರು. ಇವರೊಂದಿಗೆ ಪ್ರಭಾವದಿಂದ\nಚಿಂತನಾಶೀಲತೆಯನ್ನು ಕಳೆದುಕೊಂಡವರು ಕೂಡಾ ಈ ರೀತಿ ಯೋಚಿಸುತ್ತಾರೆ. ಇವರಿಗೆ ಎಂದೂ ಸಹಜ\nಚಿಂತನೆ ಬರುವುದಿಲ್ಲ. ಇವರು ಯಾವಾಗಲೂ ಹತ್ಯಕ್ಕೆ ವಿರುದ್ಧವಾಗಿ ಚಿಂತಿಸುತ್ತಿರುತ್ತಾರೆ.\n",
  "9.13": "ಮಹಾ ಆತ್ಮಾನಃ ತು ಮಾಮ್‌ ಪಾರ್ಥ ದೈವೀಮ್‌ ಪ್ರಕೃತಿಮ್‌ ಆಶ್ರಿತಾಃ |\n\nಭಜಂತಿ ಅನನ್ಯ ಮನಸಃ ಜ್ಞಾತ್ವಾ ಭೂತ ಆದಿಮ್‌ ಅವ್ಯಯಮ್‌ -ಓ ಪಾರ್ಥಾ, ಸಾತ್ವಿಕ ಸ್ವಭಾವದ ಹಿರಿಯ\nಮಂದಿ, ಅಳಿವ ವಿಶ್ವಕ್ಕೆಲ್ಲಾ ಅಳಿವಿರದ ನಾನೇ ಕಾರಣ ಎಂದು ತಿಳಿದು, ಒಂದೇ ಬಗೆಯಿಂದ ನನ್ನನ್ನು\nಪೂಜಿಸುತ್ತಾರೆ.\n\nಹಿಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ಆಸುರೀ ಮತ್ತು ರಾಕ್ಷಸ ಸ್ವಭಾವದವರನ್ನು ವಿವರಿಸಿದ ಕೃಷ್ಣ ಇಲ್ಲಿ ದೈವೀ\nಸ್ವಭಾವದವರನ್ನು ವಿವರಿಸುತ್ತಾನೆ. ದೈವೀ ಸ್ವಭಾವದವರು ಸದಾ ಜ್ಞಾನದ, ಬೆಳಕಿನ, ಸತ್ಯದ ದಾರಿಯಲ್ಲಿ\nಸಾಗುವವರು. ಅವರು ಭಗವಂತನನ್ನು ತಿಳಿಯುವ ಭಾಗ್ಯ ಪಡೆದವರು. ಇವರನ್ನು ಭಗವಂತ “ಮಹಾತ್ಮರು”\nಎನ್ನುತ್ತಾನೆ. ಭಗವಂತನಿಗೆ ಇವರ ಮೇಲೆ ಅಪಾರ ಪ್ರೀತಿ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ಅವರು ನನ್ನನ್ನು ಅನನ್ಯ\nಮನಸ್ಸಿನಿಂದ ಭಜನೆ ಮಾಡುತ್ತಾರೆ” ಎಂದು. ನಾವು ದೇವರನ್ನು ಪ್ರೀತಿಸುವುದು ಮತ್ತು ದೇವರು ನಮ್ಮನ್ನು\nಪ್ರೀತಿಸುವುದು ನಿಜವಾದ ಭಜನೆ. ದೈವೀ ಸ್ವಭಾವದವರು ಭಗವಂತನನ್ನು ಬಿಟ್ಟು ಉಳಿದುದೆಲ್ಲವೂ ನಶ್ವರ,\nಶಾಶ್ವತ ಸತ್ಯ ಭಗವಂತ ಮಾತ್ರ ಎನ್ನುವ ಸತ್ಯವನ್ನು ಅರಿತಿರುತ್ತಾರೆ. ಪ್ರಪಂಚದಲ್ಲಿ ಭಗವಂತ ಮತ್ತು ಆತನ\nಜ್ಞಾನ ಮಾತ್ರ ಅವ್ಯಯ. ಉಳಿದ (ದುಡ್ಡು, ಆಸ್ತಿ, ಚಿನ್ನ, ಅಧಿಕಾರ, ಇತ್ಯಾದಿ) ಎಲ್ಲವೂ ವ್ಯಯ. ನಶ್ಚರವಲ್ಲದ\nಸಂಪತ್ತು ಭಗವಂತ ಮತ್ತು ಆತನ ಜ್ಞಾನ. ಈ ರೀತಿ ಭಗವಂತನ ಚಿಂತನೆ ಮಾಡುವವರು ಮಹಾತ್ಮರು.\n\nಈ ಶ್ಲೋಕದಲ್ಲಿ ಬಂದಿರುವ ವಿಶೇಷಣ 'ಪಾರ್ಥ'. “ಪ್ರಥೆಯ ಮಗನೇ” ಎಂದು ಕೃಷ್ಣ ಅರ್ಜುನನನ್ನು\nಸಂಬೋಧಿಸುತ್ತಿದ್ದಾನೆ ಎನ್ನುವುದು ಮೇಲ್ನೋಟದ ಅರ್ಥ. ವ್ಯತ್ಪತ್ತಿ ಶಾಸ್ತ್ರೀಯ ದೃಷ್ಟಿಯಿಂದ(Etymologically)\nನೋಡಿದರೆ ಈ ವಿಶೇಷಣದ ಹಿಂದೆ ಆಧ್ಯಾತ್ಮಿಕವಾಗಿ ಬೇರೆಯೇ ಅರ್ಥವಿದೆ. “ಪ್ರಥ- ವಿಸ್ತಾರೆ' ಧಾತು. ಯಾವುದು\nಹಬ್ಬಿಕೊಂಡಿದೆಯೋ, ಯಾವುದು ಎಲ್ಲಾ ಕಡೆ ತುಂಬಿದೆಯೋ ಅದು “ಪ್ರಥ'. ಇದು ಭಗವಂತನ ಸರ್ವಗತತ್ವವನ್ನು\nಸೂಚಿಸುತ್ತದೆ. ಭಗವಂತ ಸರ್ವಗತ ಎನ್ನುವ ಸತ್ಯವನ್ನು ಅರಿತು ಅವನನ್ನು ಎಲ್ಲಾ ಕಡೆ ಕಾಣುವವರು\n'ಪಾರ್ಥರು'. ಇನ್ನೊಂದು ಅರ್ಥದಲ್ಲಿ ವೇದಾರ್ಥಭೂತನಾದ ಭಗವಂತನನ್ನು, ಅವನ ಗುಣಗಳನ್ನು, ಸದಾ ಪಾನ\nಮಾಡುವವರು “ಪಾರ್ಥರು'. ನಾವೆಲ್ಲರೂ ವೇದಾರ್ಥವನ್ನು ಪಾನ ಮಾಡುತ್ತಾ ಪಾರ್ಥರಾಗಬೇಕು. ಎಲ್ಲೆಡೆ\nಹಬ್ಬಿರುವ ಸರ್ವಗತವಾದ ಶಕ್ತಿಯನ್ನು ನಮ್ಮೊಳಗೂ ಕಾಣಬೇಕು ಎನ್ನುವುದು ಈ ಸಂಬೋಧನೆಯ ಹಿಂದಿರುವ\nಸಂದೇಶ.\n\nದೈವೀ ಸ್ವಭಾವದವರು ಭಗವಂತನನ್ನು ಯಾವಯಾವ ಬಗೆಯಲ್ಲಿ ಉಪಾಸನೆ ಮಾಡುತ್ತಾರೆ ಎನ್ನುವುದನ್ನು\nಕೃಷ್ಣ ಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ವಿವರಿಸುತ್ತಾನೆ.\n",
  "9.14": "ಸತತಮ್‌ ಕೀರ್ತಯಂತಃ ಮಾಮ್‌ ಯತಂತಃ ಚ ದೃಢ ಪ್ರತಾಃ।\n\nನಮಸ್ಯಂತಃ ಚ ಮಾಮ್‌ ಭಕ್ತ್ಯಾ ನಿತ್ಯ ಯುಕ್ತಾಃ ಉಪಾಸತೇ -ಅನುದಿನವೂ ನನ್ನಲ್ಲಿ ಬಗೆಯಿಟ್ಟು ನನ್ನನ್ನೇ\nಸೇವಿಸುತ್ತಾರೆ. ನಿರಂತರ ನನ್ನನ್ನು ಕೊಂಡಾಡುತ್ತಾ ನೇಮಗಳನ್ನು ನೆಮ್ಮಿಕೊಂಡು ಹೆಣಗುತ್ತಾ ನನಗಾಗಿ\nತಲೆಬಾಗುತ್ತಾ.\n\n“ದೈವೀ ಸ್ವಭಾವದವರು ನಿರಂತರ ನನ್ನನ್ನು ಕೀರ್ತನ ಮಾಡುತ್ತಾರೆ” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಅವರ ಪ್ರತಿಯೊಂದು\nಚಟುವಟಿಕೆಯಲ್ಲೂ ಭಗವದ್‌ ಪ್ರಜ್ಞೆ ಗಾಢವಾಗಿರುತ್ತದೆ. ಇನ್ನೊಂದು ಅರ್ಥದಲ್ಲಿ ತತವಾದ್ಯವನ್ನು ಹಿಡಿದು,\nತಂತಿಯನ್ನು ಮೀಟುತ್ತಾ ಭಗವಂತನ ಗುಣಗಾನ ಮಾಡುತ್ತಾ, ಹಾಡುತ್ತಾ(ನಾರದ ಮಹರ್ಷಿಗಳಂತೆ) ಸದಾ\nಸಂತೋಷವಾಗಿರುವವರು ದೈವೀ ಸ್ವಭಾವದವರು. ಇವರು ನಿರಂತರ, ತಮ್ಮ ಗುರಿ ತಲುಪುವತನಕವೂ ದೃಡ\nಧೀಕ್ಷೆಯಿಂದ, ಅನನ್ಯ ಪ್ರೀತಿಯಿಂದ ಉಪಾಸನೆ ಮಾಡುತ್ತಾರೆ. ಇವರಲ್ಲಿ ಇನ್ನೊಂದು ವಿಧದ ಭಕ್ತರನ್ನು ಕೃಷ್ಣ\nಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ವಿವರಿಸುತ್ತಾನೆ.",
  "9.15": "ಜ್ಞಾನಯಜ್ಞೇನ ಚ ಅಪಿ ಅನ್ಯೇ ಯಜಂತಃ ಮಾಮ್‌ ಉಪಾಸತೇ |\n\nಏಕತ್ವೇನ ಪೃಥಕ್‌ ತ್ವೇನ ಬಹುಧಾ ವಿಶ್ವತಃ ಮುಖಮ್‌-ಕೆಲವರು ಅರಿವಿನ ಮಾನಸ ಯಜ್ಞದಿಂದ ಎಲ್ಲೆಡೆ\nತುಂಬಿರುವ ನನ್ನನ್ನು ಪೂಜಿಸುತ್ತಾ ಸೇವಿಸುತ್ತಾರೆ- ಎಲ್ಲೆಡೆಯಿರುವ ಭಗವಂತನೊಬ್ಬನೇ\nಎಂದು[ಏಕಮೂರ್ತಿಯೆಂದು], ಎಲ್ಲಕ್ಕಿಂತ ಬೇರೆಯೆಂದು[ಚತುರ್ಮೂರ್ತಿಯೆಂದು], ಬಗೆಬಗೆಯ ಬಣ್ಣದವನೆಂದು\n[ಅನೇಕಮೂರ್ತಿಯೆಂದು];, ಹೀಗೆ ಹಲವಾರು ಬಗೆಯಿಂದ.\n\nಇನ್ನು ಕೆಲವರು ಭಗವಂತನ ಅರಿವಿನ ಪ್ರಪಂಚದಲ್ಲಿ ಮುಳುಗಿಬಿಟ್ಟಿರುತ್ತಾರೆ. ಧ್ಯಾನದಲ್ಲಿ ಅವರಿಗೆ ಹೊರಗಿನ\nಪ್ರಪಂಚದ ಅರಿವೇ ಇರುವುದಿಲ್ಲ. ಧ್ಯಾನದಲ್ಲಿ ಭಗವಂತನನ್ನು ಅನೇಕ ಆಯಾಮದಲ್ಲಿ ಕಾಣುವುದೇ ಅವರ\nಉಪಾಸನೆ. ಇವರ ಉಪಾಸನೆ ಧ್ಯಾನ ಪೂರ್ವಕವಾದ ಯಜ್ಞ. ಬಾಹ್ಯವಾಗಿ ಇವರನ್ನು ಮಹಾತ್ಮರು ಎಂದು\nಗುರುತಿಸುವುದು ಬಹಳ ಕಷ್ಟ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಇಂತವರು ನನ್ನನ್ನು ಒಂದಾಗಿ, ಬೇರೆಯಾಗಿ, ಬಹುವಾಗಿ\nಕಾಣುತ್ತಾರೆ” ಎಂದು. ಇಲ್ಲಿ ಏಕತ್ವೇನ ಅಂದರೆ ಭಗವಂತ ಒಬ್ಬನೆ ಎಂದು ಉಪಾಸನೆ ಮಾಡುವುದು.\nಒಂದೊಂದು ದೇಶಕ್ಕೆ, ಒಂದೊಂದು ಜಾತಿಗೆ, ಒಂದೊಂದು ಮತಕ್ಕೆ ಒಬ್ಬ ದೇವರಲ್ಲ. ಎಲ್ಲರಿಗೂ ದೇವರು\nಒಬ್ಬನೇ ಎಂದು ಉಪಾಸನೆ ಮಾಡುವುದು ಏಕತ್ವೇನ. ಪೃಥಕ್ತ್ವೇನ ಎಂದರೆ ಎಲ್ಲರಿಂದ ವಿಲಕ್ಷಣನಾದ\nಭಗವಂತನನ್ನು ಅನೇಕ ಬಗೆಯಿಂದ ಕಾಣುವುದು. ಇವರು ಭಗವಂತನನ್ನು ಧ್ಯಾನದಲ್ಲಿ ಅನೇಕ ವರ್ಣದಿಂದ\nಕಾಣುತ್ತಾರೆ. ಹೀಗೆ ವಿಶ್ವತೋಮುಖ ಭಗವಂತನನ್ನು ಏಕ ಎಂತಲೂ, ಚತುರ್ಮೂರ್ತಿ ಎಂತಲೂ, ಅನೇಕ\nಮೂರ್ತಿ ಎಂತಲೂ, ಅನೇಕ ವರ್ಣದಿಂದ ಉಪಾಸನೆ ಮಾಡುತ್ತಾರೆ.\n\nಭಗವಂತನನ್ನು ಹೇಗೆ ಅನುಸಂಧಾನ ಮಾಡಬೇಕು, ಹೇಗೆ ಮಾಡಬಾರದು ಎನ್ನುವ ಅರಿವನ್ನು ಕೊಟ್ಟ ಕೃಷ್ಣ,\nಮುಂದೆ ಭಗವಂತನ ವಿಭೂತಿಯನ್ನು ಬೇರೆ. ಬೇರೆ ಪ್ರತೀಕಗಳಲ್ಲಿ ಹೇಗೆ ಅನುಸಂಧಾನ ಮಾಡಬೇಕು\nಎನ್ನುವುದನ್ನು ವಿವರಿಸುತ್ತಾನೆ. ಇಡೀ ವಿಶ್ವದ ಅಣು ಕಣಗಳಲ್ಲಿ ತುಂಬಿರುವ ಭಗವಂತನ ಅನುಸಂಧಾನ ಹಾಗೂ\nಅದರ ವಿಶಿಷ್ಟ ಉಪಾಸನೆಯ ವಿವರವನ್ನು ಈ ಅಧ್ಯಾಯದ ಮುಂದಿನ ಭಾಗದಲ್ಲಿ ಕೃಷ್ಣ ವಿವರಿಸಿದ್ದಾನೆ. ಬನ್ನಿ ಈ\nಅಪೂರ್ವ ವಿಶಿಷ್ಟ ಜ್ಞಾನವನ್ನು ಭಗವಂತನಿಂದಲೇ ಕೇಳಿ ತಿಳಿದು ಕೃತಾರ್ಥರಾಗೋಣ.",
  "9.16": "ಅಹಮ್‌ ಕ್ರತುಃ ಅಹಮ್‌ ಯಜ್ಞಃ ಸ್ವಧಾ ಅಹಮ್‌ ಅಹಮ್‌ ಔಷಧಮ್‌ ।\n\nಮಂತ್ರಃ ಅಹಮ್‌ ಅಹಮ್‌ ಏವ ಆಜ್ಯಮ್‌ ಅಹಮ್‌ ಅಗ್ನಿಃ ಅಹಮ್‌ ಹುತಮ್‌- ನನ್ನಿಂದ ಯಾಗ. [ನನ್ನ ಕ್ರಿಯೆ ನನ್ನ\nಸ್ವರೂಪವಾದ್ದರಿಂದ ನಾನು “ಕ್ರತು”. ನನ್ನಿಂದ ಹವನ ಕ್ರಿಯೆ.[ಎಲ್ಲಾ ಬಲ್ಲವನಾದ್ದರಿಂದ \"ಯಜ್ಞ']. ಪಿತೃಗಳ ಅನ್ನ\nನನ್ನಿಂದ [ನನಗೆ ನಾನೇ ಆಸರೆಯಾದ್ದರಿಂದ “ಸ್ವಧಾ. ನನ್ನಿಂದ ಮನುಷ್ಯರ ಆಹಾರ([ಬೆಂದವರಿಗೆ\nಆಸರೆಯಾದ್ದರಿಂದ 'ಔಷಧ']. ಮಂತ್ರ ನನ್ನಿಂದ[ತಿಳಿವಿತ್ತು ಸಲಹುದರಿಂದ \"ಮಂತ್ರ. ನನ್ನಿಂದಲೇ ತುಪ್ಪ\n[ಎಲ್ಲಕ್ಕೆಂತ ಹಿರಿಯನಾದ್ದರಿಂದ “ಆಜ್ಯ']. ನನ್ನಿಂದ ಬೆಂಕಿ.[ನಾನೇ ಚಲಿಸದ ವಿಶ್ವಕ್ಕೆ ಚಲನೆ ನೀಡುವುದರಿಂದ\n\"ಅಗ್ನಿ. ನನ್ನಿಂದ ಹೋಮದ ಹವ್ಮಿ(ಭಕ್ತರು ಕರೆವುದರಿಂದ ನಾನೇ \"ಹುತ'].\n\nಭಗವಂತನ ಉಪಾಸನೆಗೆ ಮೂರು ಪ್ರತೀಕವನ್ನು ಶಾಸ್ತ್ರಕಾರರು ಹೇಳಿದ್ದಾರೆ. ವೇದದಲ್ಲಿ ಆ ಮೂರು\nಪ್ರತೀಕಗಳಿಂದ ಉಪಾಸನೆಯೇ ನಮಗೆ ಎಲ್ಲಾ ಕಡೆ ಸಿಗುವುದು. ಅವುಗಳೆಂದರೆ ಅಗ್ನಿಪ್ರತೀಕ, ವಾಯುಪ್ರತೀಕ\nಮತ್ತು ಆದಿತ್ಯಪ್ರತೀಕ. ಭೂಸ್ತರದಲ್ಲಿ ಭಗವಂತನ ಉಪಾಸನೆ ಅಗ್ನಿಪ್ರತೀಕದಲ್ಲಿ. ಅಂತರಿಕ್ಷ ಸ್ತರದಲ್ಲಿ ಆದಿತ್ಯ\nಮುಖದಲ್ಲಿ ಮತ್ತು ಅಂತರಂಗದಲ್ಲಿ ಭಗವಂತನ ಉಪಾಸನೆ ವಾಯುವಿನ ಪ್ರತೀಕದಲ್ಲಿ. ಭೂಮಿಯಲ್ಲಿ\nಸಾಮಾನ್ಯವಾಗಿ ಮನುಷ್ಯರು ಜ್ಞಾನಮಾರ್ಗಕ್ಕಿಂತ ಹೆಚ್ಚು ಕರ್ಮ ಮಾರ್ಗಕ್ಕೆ ಅಂಟಿಕೊಂಡವರು. ಇಂಥವರಲ್ಲಿ\nಜ್ಞಾನಕ್ಕಿಂತ ಕರ್ಮಕ್ಕೆ ಒತ್ತು ಹೆಚ್ಚು. ಕೆಲವರು ಬೆಳಿಗ್ಗೆಯಿಂದ ಸಂಜೆ ತನಕ ಪೂಜೆ ಮಾಡುತ್ತಾರೆ. ಆದರೆ ತಾವು\nಮಾಡುವ ಅನುಷ್ಠಾನದ ಜ್ಞಾನವೇ ಅವರಿಗಿರುವುದಿಲ್ಲ. ಇವರಿಗೆ ಜ್ಞಾನ ಸಂಪಾದನೆ ದ್ವಿತೀಯಕ(secondary)).\nಇದು ಮನುಷ್ಯನ ದೌರ್ಬಲ್ಯ. ನಮಗೆ ನಮ್ಮ ಮಡಿವಂತಿಕೆಯಲ್ಲಿರುವಷ್ಟು ಒತ್ತು ಜ್ಞಾನದಲ್ಲಿರುವುದಿಲ್ಲ! ತಿಳಿಯದ\nಬಾಹ್ಯಾನುಷ್ಠಾನದಲ್ಲಿ ಕಾಲಹರಣ ಮಾಡುವುದಕ್ಕಿಂತ ಪಾಠ ಪ್ರವಚನದಿಂದ ಸ್ವಲ್ಪಮಟ್ಟಿನ ಜ್ಞಾನ\nಗಳಿಸಿಕೊಳ್ಳುವುದು ದೇವರು ಮೆಚ್ಚುವ ಮಹಾ ಪೂಜೆ ಎನಿಸುತ್ತದೆ.\n\nಕರ್ಮ ಪ್ರಧಾನವಾಗಿರುವವರಿಗೆ ಭಗವಂತನ ಅನುಷ್ಠಾನ ಹೇಗಿರಬೇಕು. ಎನ್ನುವುದನ್ನು ಕೃಷ್ಣ ಇಲ್ಲಿ\nವಿವರಿಸಿದ್ದಾನೆ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಅಹಮ್‌ ಕ್ರತುಃ ಅಹಮ್‌ ಯಜ್ಞಃ” ಎಂದು. ಭಗವಂತನ\nಆರಾಧನೆಗೋಸ್ಕರ ಮಾಡತಕ್ಕಂತಹ ಅಗ್ನಿ ಆರಾಧನೆಯ ಪ್ರಕ್ರಿಯೆ “ಕ್ರತು”. ಇಲ್ಲಿ ಯಜ್ಞದ ಮೂಲಕ\nಭಗವಂತನಿಗೆ ಆಹುತಿ ಕೊಡುವಾಗ ಈ ರೀತಿ ಹೇಳಿ ಆಹುತಿ ಕೊಡುತ್ತೇವೆ: ಅಗ್ನ ಯೇ ಸ್ವಾಹಾ-ಅಗ್ನ ಯ ಇದಂನ\nಮಮ; ಪ್ರಜಾಪತೆಯೇ ಸ್ವಾಹ ಪ್ರಜಾಪತಯ ಇದಂ ನ ಮಮ; ಇಂದ್ರಾಯ ಸ್ವಾಹಾ-ಇಂದ್ರಾಯ ಇದಂ ನ\nಮಮ; ಸೂರ್ಯಾಯ ಸ್ವಾಹಾ-ಸೂರ್ಯಾಯ ಇದಂ ನ ಮಮ; ವಾಯವೇ ಸ್ವಾಹಾ-ವಾಯವ ಇದಂ ನ ಮಮ;\nವರುಣಾಯ ಸ್ವಾಹಾ-ವರುಣಾಯ ಇದಂ ನ ಮಮ,..ಇತ್ಯಾದಿ. ಹೀಗೆ ಬೇರೆ ಬೇರೆ ಪ್ರತೀಕದಲ್ಲಿ ಭಗವಂತನಿಗೆ\nಆಹುತಿ ಕೊಡುವುದು ಯಜ್ಞ. ಇಲ್ಲಿ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ನೀವು ಮಾಡುವ ಕ್ರತುವಿನ ನಿಯಾಮಕ ನಾನು” ಎಂದು.\nನಾವು ಯಾವ ಪ್ರತೀಕದಲ್ಲಿ ಪೂಜೆ ಮಾಡಿದರೂ ಅದು ಸಲ್ಲುವುದು ಆ ದೇವತೆಯ ಅಂತರ್ಯಾಮಿ\n\nಭಗವಂತನಿಗೆ. ಉದಾಹರಣೆಗೆ ಗಣಹೋಮ, ಚಂಡಿಕಾಹೋಮ, ನವಗ್ರಹಹೋಮ ಇತ್ಯಾದಿ. ಇಲ್ಲಿ ನಾವು\nಯಾವ ದೇವತೆಯ ಪ್ರತೀಕದಲ್ಲಿ ಯಜ್ಞ ಮಾಡಿದರೂ ಕೂಡಾ ಆ ಯಜ್ಞ ಭಗವಂತನಿಗೆ ಸಲ್ಲುತ್ತದೆ ಎನ್ನುವ\nಅನುಸಂಧಾನ ನಮ್ಮಲ್ಲಿರಬೇಕು. ಭಗವಂತ ಅನೇಕ ಶಕ್ತಿ ರೂಪದಲ್ಲಿ ಅಭಿವ್ಯಕ್ತನಾದರೂ ಕೂಡಾ, ಸರ್ವ\nನಿಯಾಮಕ ಭಗವಂತ ಒಬ್ಬನೇ. [ನಮಗೆ ಬಂದಿರುವ ಆಪತ್ತಿನ ನಿವಾರಣೆಗಾಗಿ ಜೋತಿಷಿಗಳು ಭಗವಂತನ\nಆಯಾ ಶಕ್ತಿ ಪ್ರತೀಕವನ್ನು ಪೂಜಿಸುವಂತೆ ಹೇಳುತ್ತಾರೆಯೇ ಹೊರತು, ಭಗವಂತ ಅನೇಕ ಅಲ್ಲ]. ದೇವತೆಯ\nಒಳಗಿರುವ ಭಗವಂತ ಪ್ರೀತನಾದಾಗ ಮಾತ್ರ ಅದು ಆ ದೇವತೆಗೂ ಮತ್ತು ಭಗವಂತನಿಗೂ ಸಂದಂತೆ.\nಆದ್ದರಿಂದ ಒಂದೊಂದು ದಿನ ಒಂದೊಂದು ದೇವತೆಗೆ ಪ್ರೀತಿಯಾಗುವುದಕ್ಕೋಸ್ಕರ ಕರ್ಮ ಮಾಡುವುದಲ್ಲ.\nಸರ್ವಾಂತರ್ಯಾಮಿ ಭಗವಂತನಿಗೆ ನಮ್ಮ ಪೂಜೆ ಮೀಸಲಾಗಿರಬೇಕು.\n\nನಮ್ಮ ದೇಹದೊಳಗೆ ತತ್ತ್ವಾಭಿಮಾನಿ ದೇವತೆಗಳಿದ್ದಾರೆ. ದೇವತೆಗಳೆಲ್ಲರೂ ಗುರು ಸ್ಥಾನೀಯರು. ಅವರು\nದೇವರ ಪರಿವಾರ. ಅವರನ್ನು ನಿಯಮನ ಮಾಡಿಕೊಂಡು ಆ ಭಗವಂತನಿದ್ದಾನೆ. ಈ ತತ್ತ್ವಾಭಿಮಾನಿ\nದೇವತೆಗಳು. ಭಗವಂತನ ಅನುಗ್ರಹದಿಂದ ನಮ್ಮನ್ನು ಸನ್ಮಾರ್ಗದಲ್ಲಿ ನಡೆಸಲಿ ಎಂದು ಅವರ\nಅಂತರ್ಯಾಮಿಯಾದ ಭಗವಂತನನ್ನು ಆರಾಧಿಸುವುದು ಯಜ್ಞ.\n\nನಾವು ನಿತ್ಯ ಪೀಠದಲ್ಲಿ ಮಾಡುವ ಪೂಜೆ ತತ್ತ್ವಾಭಿಮಾನಿ ದೇವತೆಗಳನ್ನು ಕುರಿತು ಮಾಡುವ ಯಜ್ಞವಾದರೆ,\nಶ್ರಾದ್ಧ- ಪಿತೃದೇವತೆಗಳನ್ನು ಕುರಿತು ಮಾಡುವ ಯಜ್ಞ. ನಮ್ಮಲ್ಲಿ ಅನೇಕರಿಗೆ ಒಂದು ತಪ್ಪು ಕಲ್ಪನೆ ಇದೆ. ಶ್ರಾದ್ಧ\n'ದೇಹ ತ್ಯಾಗ ಮಾಡಿದ ಜೀವಕ್ಕೆ' ಎಂದು. ಆದರೆ ಇದು ಸರಿಯಲ್ಲ. ಶ್ರಾದ್ಧ ಸ್ಥೂಲ ದೇಹವನ್ನು ತ್ಯಜಿಸಿ ಸೂಕ್ಷ್ಮ\nಶರೀರದಲ್ಲಿರುವ ಜೀವವನ್ನು ನಿಯಂತ್ರಿಸುವ 'ಪಿತೃದೇವತೆಗಳಿಗೆ' ಮಾಡುವಂತ್ತದ್ದು. ವಿಶೇಷವಾಗಿ ಹತ್ತು ಮಂದಿ\nವಿಶ್ವೇದೇವತೆಗಳು(ಕ್ರತು,ದಕ್ಷ, ವಾಸು, ಸತ್ಯ, ಕಾಮ, ಕಾಲ,ಧುರಿ, ಲೋಚನ,ಪುರೂರವ ಆರ್ದ್ರವ); ಇವರಲ್ಲಿ\nಪುರೂರವ ಮತ್ತು ಆರ್ದ್ರವರದ್ದು ಪಿತೃಗಣದ ನಿಯಮನ ಮಾಡತಕ್ಕಂತಹ ಖಾತೆ(account). ವಿತೃದೇವತೆಗಳ\nಗಣ ಹತ್ತು(ನೂರು ಮಂದಿ ಪಿತೃಗಳಲ್ಲಿ ಇವರು ಪ್ರಧಾನರು): ಯಮ, ಸೋಮ, ಕವ್ಯವಾಹ(ಇವರು ಮೂವರು\nಪಿತೃಪತಿಗಳು), ಸೋಮಸದರು, ಅಗ್ನಿಷ್ಟಾತ್ತರು, ಬಹಿರ್ಷದರು, ಸೋಮಪರು, ಹವಿರ್ಭುಜರು, ಅಜ್ಯಪರು,\nಸುಕಾಲಿಗಳು. ನಾವು ಪಿಂಡ ಹಾಕುವುದು ಜೀವದ ಹಸಿವು ನೀಗಲಿಕ್ಕೆ ಅಲ್ಲ. ನಮ್ಮ ಹಿರಿಯರು ಸ್ವರ್ಗಕ್ಕೆ ಅಥವಾ\nನರಕಕ್ಕೆ ಹೋಗುವುದು ಅವರು ಮಾಡಿದ ಕರ್ಮಫಲದಿಂದಲೇ ಹೊರತು ನಾವು ಹಾಕಿದ ಶ್ರಾದ್ಧದಿಂದಲ್ಲ. ಶ್ರಾದ್ಧ\nಮಾಡುವ ಉದ್ದೇಶ ಏನೆಂದರೆ ಪಿತೃದೇವತೆಗಳ ಸ್ವಾದೀನದಲ್ಲಿರುವ ಜೀವ ಯಾವುದೋ ದುರಿತದ\nಪ್ರಭಾವದಿಂದ ದಾರಿಯಲ್ಲಿ ತಡೆಯನ್ನು (Road blockers) ಎದುರಿಸಬೇಕಾಗಬಹುದು. ಆ ಸಮಯದಲ್ಲಿ ಅದನ್ನು\nನಿವಾರಣೆ ಮಾಡುವ ಕರ್ಮಾನುಷ್ಠಾನ ಆ ಸೂಕ್ಷ್ಮ ಶರೀರದಲ್ಲಿ ಇರುವುದಿಲ್ಲ. ಅದಕ್ಕೋಸ್ಕರ ಅಂತಹ\nಪ್ರತಿಬಂಧಕಗಳಿಂದ ಅವರನ್ನು ಪಾರು ಮಾಡಿ ಮುಂದೆ ಸಾಗಲು ನೆರವು ಕೋರಿ ಮಾಡುವ ಪಿತೃದೇವತೆಗಳ\nಪೂಜೆಯೇ ಶ್ರಾದ್ಧ. ಒಟ್ಟಾರೆ ಇದು ಹಿರಿಯರು ಸತ್ತ ದಿನದ ನೆನಪು, ಅವರಿಗೆ ಕೃತಜ್ಞತೆ ಮತ್ತು ಪಿತೃದೇವತೆಗಳ\nಪೂಜೆ.\n\nಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಸ್ವಧಾ ಅಹಮ್‌” ಎಂದು. ಮಂತ್ರಗಳು ವಿಳಾಸದಂತೆ, “ಸ್ವಾಹ' ತತ್ತ್ವಾಭಿಮಾನಿ\nದೇವತೆಗಳಿಗಾದರೆ “ಸ್ವಧಾ' ಪಿತೃದೇವತೆಗಳಿಗೆ. ನನ್ನ ಮುಖೇನವೇ ಶ್ರಾದ್ಧ ಪಿತೃದೇವತೆಗಳಿಗೆ ಸಲ್ಲುವುದು\nಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.\n\nತತ್ತ್ವಾಭಿಮಾನಿದೇವತೆಗಳು ಮತ್ತು ಪಿತೃದೇವತೆಗಳ ನಂತರ ಮನುಷ್ಯರು. ಮನುಷ್ಯರ ಮುಖ್ಯವಾದ ಆಹಾರ\n'ಓಷಧಿ'. ಫಲ ಕೊಟ್ಟು ಸಾಯುವ ಗಿಡವನ್ನು ಸಂಸ್ಕೃತದಲ್ಲಿ \"ಓಷಧಿ' ಎನ್ನುತ್ತಾರೆ. ಆ ಗಿಡದ ಪ್ರಸವವೇ ಅದರ\nಸಾವು. ಮನುಷ್ಯ ತಿನ್ನುವ ದವಸಧಾನ್ಯ ಎಲ್ಲವೂ ಓಷಧಿಗಳು. ಇಂತಹ ಓಷಧಿಗಳ ಸಮುದಾಯವೇ ಔಷಧಿ. ಕೃಷ್ಣ\nಹೇಳುತ್ತಾನೆ “ಅಹಮ್‌ ಔಷಧಮ್‌” ಎಂದು. ನಾವು ತಿನ್ನುವ ದವಸ ಧಾನ್ಯ ಸಲ್ಲುವುದು ಕೂಡಾ ವೈಶ್ವಾನರನಾಗಿ\nಒಳಗೆ ಕುಳಿತಿರುವ ಭಗವಂತನಿಗೆ. ಔಷಧ ಕೊಡತಕ್ಕವ, ಅದರಿಂದ ರೋಗ ನಿವಾರಿಸುವವ, ಹಸಿವು ನಿವಾರಿಸಿ\nರಕ್ಷಣೆ ಮಾಡುವವ ಭಗವಂತ.\n\nನಾವು ಬೇರೆಬೇರೆ ಮಂತ್ರಗಳಿಂದ ಆಹುತಿಯನ್ನು ಕೊಡುತ್ತೇವೆ. ಈ ಹಿಂದೆ ಹೇಳಿದಂತೆ ಮಂತ್ರ ವಿಳಾಸವಿದ್ದಂತೆ.\nಕೊಡುವ ಆಹುತಿ ಎಲ್ಲವೂ ಭಗವಂತನಿಗೆ ಸೇರುವುದಾದರೆ ಬೇರೆಬೇರೆ ವಿಳಾಸವೇಕೆ? ಕೃಷ್ಣ ಹೇಳಿದ: “ಬೇರೆ\nಬೇರೆ ವಿಳಾಸದಲ್ಲಿರುವ ನನಗೆ” ಎಂದು! ಭಗವಂತ ಏಕ ಆದರೆ ಆತನ ರೂಪ ಅನೇಕ. ನಾವು ಯಾವ\nಮಂತ್ರದಿಂದ ಕಳುಹಿಸಿದರೂ ಕೂಡಾ-ಅದು ಸೇರುವುದು ಎಲ್ಲಾ ಮಂತ್ರದಿಂದ ವಾಚ್ಯನಾದ, ಸರ್ವಶಬ್ದವಾಚ್ಯ\nಭಗವಂತನನ್ನು. ಹೀಗೆ ಬೇರೆಬೇರೆ ಶಕ್ತಿ ರೂಪವನ್ನು ಬೇರೆಬೇರೆ ದೇವತಾ ಪ್ರತೀಕದಲ್ಲಿ ಪೂಜಿಸಿದರೂ ಕೂಡಾ\nಪ್ರತಿಯೊಂದು ನಾಮವೂ ಸಹ ಅಂತತಃ ಭಗವಂತನನ್ನೇ ಹೇಳುತ್ತದೆ. ಎಲ್ಲವುದರ ಸಾರವೂ ಭಗವಂತ. ಇದಕ್ಕೆ\nಉತ್ತಮ ಉದಾಹರಣೆ ತೆಂಗಿನಕಾಯಿ. ಸಿಷ್ಟೆ ಸಹಿತವಾಗಿರುವ ತೆಂಗಿನಕಾಯಿ ಉರಿಯುವ ಬೆಂಕಿಯಂತೆ;\nಸಿಪ್ಪೆಯೊಳಗಿನ ಕಾಯಿ ಬೆಂಕಿಯ ಅಂತರ್ಯಾಮಿ ಅಗ್ನಿ ದೇವತೆಯಂತೆ; ಚಿಪ್ಪಿನ ಒಳಗಿನ ಕೊಬ್ಬರಿ ಅಗ್ನಿ\nದೇವತೆಯೊಳಗಿನ ಭಗವಂತನಂತೆ. ಇಲ್ಲಿ ನಾವು ಎಲ್ಲವನ್ನೂ ಕರೆಯುವುದು ತೆಂಗಿನಕಾಯಿ ಅಥವಾ ಅಗ್ನಿ\nಎಂತಲೆ. ಹೇಗೆ ನಿಜವಾದ ತೆಂಗಿನಕಾಯಿ ಒಳಗಿನ ಸಾರವೋ ಹಾಗೇ ನಿಜವಾದ ಅಗ್ನಿ ಅಂತತಃ\nಅಂತರ್ಯಾಮಿ ಭಗವಂತ. ಈ ಶ್ಲೋಕದಲ್ಲಿ ಕೃಷ್ಣ ಇದನ್ನೇ “ಅಹಮ್‌ ಅಗ್ನಿಃ” ಎಂದಿರುವುದು.\n\nಕೃಷ್ಣ ನಾವು ಆಹುತಿಯಾಗಿ ಕೊಡುವ ಒಂದು ಪ್ರಮುಖ ವಸ್ತುವನ್ನು ಉದಾಹರಣೆಯಾಗಿ ತೆಗೆದುಕೊಂಡು\nಹೇಳುತ್ತಾನೆ “ಅಹಮ್‌ ಏವ ಆಜ್ಯಮ್‌” ಎಂದು. ಆಜ್ಯ ಎಂದರೆ ತುಪ್ಪ. ಅಜ್ಯದಲ್ಲಿ ದೇವತೆಗಳನ್ನು ತಣಿಸುವ ವಿಶಿಷ್ಟ\nಶಕ್ತಿ ಇದೆ. ಆಜ್ಯದಲ್ಲಿ ವಿಶಿಷ್ಟ ಶಕ್ತಿಯಾಗಿ ನಾನಿದ್ದೇನೆ ಎನ್ನುವ ಕೃಷ್ಣ ನಾನೇ ಹೋಮದ ಹವಿ (ಅಹಮ್‌ ಹುತಮ್‌)\nಎನ್ನುತ್ತಾನೆ.\n\nಹವಿಸ್ಸು ಎಂದರೆ ಭಗವಂತನಿಗೆ ಅರ್ಪಿಸುವ ಹೋಮ ದ್ರವ್ಯ. ಆ ಹವಿಸ್ಸಿನಲ್ಲಿ ವಿಶೇಷ ಶಕ್ತಿ ಇರುವುದು ಆ\nಭಗವಂತನಿಂದ. ನಾವು ಅರ್ಪಿಸುವ ಹವಿಸ್ಸು ಎಂದೂ ವ್ಯರ್ಥವಲ್ಲ. ಅಗ್ನಿಗೆ ಅರ್ಪಿಸಿದ ಹವಿಸ್ಸು ಅಗ್ನಿಯಿಂದ ಹೊರ\nಹೊಮ್ಮುವ ಏಳು ಬಣ್ಣಗಳ ಮುಖೇನ ವಾತಾವರಣದಲ್ಲಿನ ಸೂರ್ಯ ಕಿರಣದೊಂದಿಗೆ ಸೇರಿ ಸಮಾಜಕ್ಕೆ\nಫಲವನ್ನು ಕೊಡುತ್ತದೆ. ಹವಿರ್ಭಾಗವನ್ನು ಸ್ವೀಕರಿಸುವ ಭಗವಂತ ಹವಿರ್ಹರಿಃ . \"ಸರ್ವ ದೇವ ನಮಸ್ಕಾರಃ\nಕೇಶವಂ ಪ್ರತಿಗಚ್ಛತಿ”. ಭಗವಂತ ಎಲ್ಲಾ ಶಬ್ದಗಳಿಂದ ವಾಚ್ಯನಾದವನು. ಆದ್ದರಿಂದ ಯಾವ ಶಬ್ದವನ್ನು\nಹೇಳಿದರೂ ಅದು ಸೇರುವುದು ಅವನನ್ನೇ. ಹೀಗೆ ಹವಿಸ್ಸನ್ನು ಸ್ವೀಕರಿಸಿ ಭಕ್ತರ ಪಾಪವನ್ನು ಪರಿಹರಿಸುವ\nಭಗವಂತ ಹವಿರ್ಹರಿಃ .\n\nಈ ಶ್ಲೋಕವನ್ನು ಇನ್ನೊಂದು ಆಯಾಮದಲ್ಲಿ ನೋಡಿದರೆ, ಇಲ್ಲಿ ಬರುವ ಒಂದೊಂದು ಶಬ್ದದಲ್ಲೂ ಭಗವಂತನ\nಗುಣಾನುಸಂಧಾನವನ್ನು ಕಾಣುತ್ರೇವೆ.\n\nಕ್ರತುಃ : ಭಗವಂತನೇ ಕ್ರತು ಶಬ್ದದ ಮುಖ್ಯಾರ್ಥ. 'ಕ್ರತು' - ಕ್ರಿಯೆ, ಜ್ಞಾನ, ಇತ್ಯಾದಿ ಅರ್ಥವನ್ನು ಕೊಡುತ್ತದೆ.\nಕ್ರಿಯಾ ಸ್ವರೂಪ, ಜ್ಞಾನ ಸ್ವರೂಪ ಭಗವಂತ ಕ್ರತುಃ. ನಮ್ಮಲ್ಲಿ ನಂಬಿಕೆ, ಇಚ್ಛಾಶಕ್ತಿ, ಕ್ರಿಯಾಶಕ್ತಿ ಹಾಗೂ\nಅನುಕೂಲತೆ ಕೊಟ್ಟು, ನಮ್ಮ ಹಿಂದೆ ನಿಂತು, ಕ್ರಿಯಾ ಕಲಾಪಗಳನ್ನು ನಡೆಸುವ, ಜ್ಞಾನ ಸ್ವರೂಪನೂ, ಕರ್ಮದ\nಕಟ್ಟಿನಿಂದ ನಮ್ಮನ್ನು ಪಾರು ಮಾಡುವನೂ ಆದ ಭಗವಂತ ಕ್ರತುಃ. ಯಜ್ಞ: ಯಜ್ಞ ಅಂದರೆ ಎಲ್ಲವನ್ನೂ\nತಿಳಿದವನು. ಜ್ಞಾನರೂಪಿಯಾಗಿ ಎಲ್ಲೆಡೆ ಇರುವ ಭಗವಂತ, ಎಲ್ಲಾ ಕ್ರಿಯೆಗಳಿಂದ ಎಲ್ಲರೂ ಆರಾಧಿಸಬೇಕಾದ\nಯಜ್ಞದ ಅಂತರ್ಯಾಮಿ. ಸ್ವಧಾಃ: ಎಂದರೆ ತನ್ನನ್ನು ತಾನು ಆದರಿಸಿ ನಿಂತ ಸರ್ವ ನಿಯಾಮಕ. ಔಷಧಃ:\nಭಗವಂತ “ಔಷಧಃ'. ಎಂದರೆ ಸಂಸಾರ ತಾಪದಲ್ಲಿ ಬಿದ್ದು ಒದ್ದಾಡುವವ (ಔಷರು)ರಿಗೆ ಆಸರೆ-ಮೋಕ್ಷಪ್ರದ.\nಮಂತ್ರಃ: ಜ್ಞಾನಪೂರ್ವಕವಾಗಿ ಅನುಸಂಧಾನ ಮಾಡುವವರನ್ನು ರಕ್ಷಣೆ ಮಾಡುವ ಭಗವಂತ 'ಮಂತ್ರಃ'.\n[ಮಂತ್ರ ನಮ್ಮನ್ನು ರಕ್ಷಣೆ ಮಾಡುವುದು ನಾವು ತಿಳಿದು ಪಠಿಸಿದಾಗ ಮಾತ್ರ. ಇಲ್ಲದಿದ್ದರೆ ಕಿಂಚಿತ್‌ ಫಲ ಮಾತ್ರ\nದೊರೆಯಬಹುದೇ ಹೊರತು ನಿಜವಾದ ಮಹಾಫಲವಲ್ಲ]. ಆಜ್ಯಃ। ಭಗವಂತ ಎಲ್ಲಕ್ಕಿಂತ ದೊಡ್ಡ ವಸ್ತು ಆದ್ದರಿಂದ\nಆತ “ಆಜ್ಯಃ', ಅಗ್ನಿಃ; ಚಲಿಸದೇ ಇರುವ ವಸ್ತುವಿಗೆ ಚಲನೆ ಕೊಡುವ ಭಗವಂತ “ಅಗ್ನಿಃ”, ಹುತಃ; ಎಲ್ಲಾ ಭಕ್ತರಿಂದ\nಆಹುತನಾದ್ದರಿಂದ ಭಗವಂತ “ಹುತಃ”.\n",
  "9.17": "ಪಿತಾ ಅಹಮ್‌ ಅಸ್ಯ ಜಗತಃ ಮಾತಾ ಧಾತಾ ಪಿತಾಮಹಃ |\n\nವೇದ್ಯಮ್‌ ಪವಿತ್ರಮ್‌ ಓಂಕಾರಃ ಋಕ್ ಸಾಮ ಯಜುಃ ಏವ ಚ- ನಾನು ಈ ಜಗದ ತಂದೆ, ತಾಯಿ, ಪೋಷಕ\nಮತ್ತು ಅಜ್ಜ-ಮುತ್ತಜ್ಞ.[ಸಲಹುವುದರಿಂದ 'ಪಿತೃ'. ಅರಿಯುವುದರಿಂದ \"ಮಾತೃ'. ಬೆಳೆಸುವುದರಿಂದ 'ಧಾತೃ'.\nತಂದೆಗಿಂತಲೂ ಹಿರಿಯನಾದ್ದರಿಂದ “ಪಿತಾಮಹ'”] ಜಗವೆಲ್ಲಾ ತಿಳಿಯಬೇಕಾದವನು. ಜಗಕೆ ಪಾವನನಾದವನು.\nಓಂಕಾರದಿಂದ, ಋಗ್ವೇದ-ಸಾಮವೇದ-ಯಜುರ್ವೇದಗಳಿಂದ ವಾಚ್ಯನಾದವನು. [ಓಂ'. ಎಂದು\nಕರೆಸಿಕೊಳ್ಳುವುದರಿಂದ 'ಓಂಕಾರ'. ಪೂಜನೀಯನಾದ್ದರಿಂದ “ಋಕ್'. ಸಮಾನನಾದ್ದರಿಂದ “ಸಾಮ.\nಯಜ್ಞಗಳಿಂದ ಆರಾಧ್ಯನಾದ್ದರಿಂದ “ಯಜುಸ್‌\n\nಬದುಕಿನ ಸಂಬಂಧಗಳಿಗೆ ಸಂಬಂಧಿಸಿ ಭಗವಂತನ ಉಪಾಸನೆಯನ್ನು ಕೃಷ್ಣ ಇಲ್ಲಿ ವಿವರಿಸುತ್ತಾನೆ. ಕೃಷ್ಣ\n\nಹೇಳುತ್ತಾನೆ “ಪಿತಾ ಅಹಮ್‌ ಅಸ್ಯ ಜಗತಃ ಮಾತಾ ಧಾತಾ ಪಿತಾಮಹಃ” ಎಂದು. ಅಂದರೆ “ನಾನೇ ತಂದೆ,\n\nನಾನೇ ತಾಯಿ, ನಾನೇ ಧಾರಕ ಮತ್ತು ಪಿತಾಮಹ”. ನಮಗೆ ತಿಳಿದಂತೆ ಒಬ್ಬರು ತಂದೆಯಾಗಬಹುದು ಅಥವಾ\n\nತಾಯಿಯಾಗಬಹುದು. ಆದರೆ ಒಬ್ಬರೇ ತಾಯಿ-ತಂದೆ ಎರಡೂ ಆಗುವುದು ಸಾಧ್ಯವಿಲ್ಲ. ಇದು ಭಗವಂತನಲ್ಲಿ\n\nಮಾತ್ರ ಸಾಧ್ಯ. ಭಗವಂತ ಎಲ್ಲರಿಗೂ ಅಪ್ಪ ಮತ್ತು ಎಲ್ಲರಿಗೂ ಅಮ್ಮ. ತಂದೆಯೊಳಗೆ “ತಂದೆ'ಯಾಗಿ,\n\nತಾಯಿಯೊಳಗೆ 'ತಾಯಿ'ಯಾಗಿ ತುಂಬಿರುವ ಶಕ್ತಿ ಆ ಭಗವಂತ. ಇದನ್ನು ನಾವು ಈ ರೀತಿ ಸ್ತುತಿಸುತ್ತೇವೆ:\nತ್ವಮೇವ ಮಾತಾಚ ಪಿತಾ ತ್ವಮೇವ, ತ್ವಮೇವ ಬಂಧುಶ್ಚ ಸಖಾ ತ್ವಮೇವ\n\nತ್ವಮೇವ ವಿದ್ಯಾ ದ್ರವಿಣಂ ತ್ವಮೇವ, ತ್ವಮೇವ ಸರ್ವಂ ಮಮ ದೇವ ದೇವ\nಗಾಯತ್ತಿಯಲ್ಲಿ ಮೂಲತಃ ಈ ಅನುಷ್ಠಾನವಿದೆ. “ತತ್ಸವಿತುರ್ವರೇಣ್ಯಂ ಭರ್ಗಃ” ಎನ್ನುವಲ್ಲಿ ಭಗವಂತ ಜಗತ್ತನ್ನು\nಸೃಷ್ಟಿ ಮಾಡಿದ ತಂದೆ ಎನ್ನುವ ಅರ್ಥವಿದೆ. ಸವಿತ. ಎಂದರೆ ಜಗತ್ತನ್ನು ಹೆತ್ತವನು ಎಂದರ್ಥ.\nಪ್ರಳಯಕಾಲದಲ್ಲಿ ಜಗತ್ತನ್ನು ತನ್ನ ಉದರದಲ್ಲಿ ಧರಿಸಿ, ಸೃಷ್ಟಿ ಕಾಲದಲ್ಲಿ ಅದನ್ನು ಭಗವಂತ ಹೆತ್ತ. ಹೆತ್ತು ಹೊತ್ತು\nಸಲಹುವವಳು “ತಾಯಿ'-ಆದ್ದರಿಂದ ಭಗವಂತ ತಾಯಿಯೂ ಹೌದು. ಅಷ್ಟೇ ಅಲ್ಲ, ಪ್ರತಿಯೊಬ್ಬ ತಾಯಿಯೊಳಗಿದ್ದು\nಆ ತಾಯಿಯ ತಾಯ್ತನವನ್ನು ಜಾಗೃತಗೊಳಿಸಿ, ತಾಯಿಯೊಳಗೆ ತಾಯಿಯಾಗಿ ತುಂಬಿರುವ ಭಗವಂತ, ಎಲ್ಲಾ\nತಂದೆಯಂದಿರ ಒಳಗೂ ಇದ್ದು, ಅವರಲ್ಲಿ ಪಿತೃತ್ವ ಜಾಗೃತಗೊಳಿಸುವ ತಂದೆ. ಪಿತಾ ಅನ್ನುವ ಪದದ ನಿರ್ವಚನ\nನೋಡಿದರೆ “ತಂದೆ' ಅನ್ನುವುದು ಕೇವಲ ರೂಢಿ ಅರ್ಥ. ಶ್ರುತಿಯಲ್ಲಿ ಹೀಗೆ ಹೇಳುತ್ತಾರೆ:\n\nಯೋನಃ ಪಿತಾ ಜನಿತಾಯೋ ವಿಧಾತಾ ಧಾಮಾನಿ ವೇದ ಭುವನಾನಿ ವಿಶ್ವಾ|\n\nಯೋ ದೇವಾನಾಂ ನಾಮಧಾ ಏಕ ಏವ ತಂ ಸಂಪ್ರಶ್ನಂಭುವನಾ ಯಂತ್ಯನ್ಯಾ||\nಇಲ್ಲಿ ಪಿತಾ ಮತ್ತು ಜನಕನನ್ನು ಬೇರೆ ಬೇರೆಯಾಗಿ ಹೇಳುತ್ತಾರೆ. ಅವನು ನಮ್ಮ ತಂದೆ, ಅವನು ನಮ್ಮ ಜನಕ.\nಅಂದರೆ: ಹುಟ್ಟಿಸಿದವನೂ ಅವನೇ, ರಕ್ಷಕನೂ ಅವನೇ.\nಲೋಕದಲ್ಲಿ ಗಂಡು ಹೆಣ್ಣಲ್ಲ, ಹೆಣ್ಣು ಗಂಡಲ್ಲ. ಆದರೆ ಭಗವಂತ ಎಲ್ಲರ ಬಿಂಬರೂಪ. ಆದ್ದರಿಂದ ಭಗವಂತ\nಉಭಯಲಿಂಗ-ಆತ ಸ್ತ್ರೀಪುಂಸಕ. ಆದರೆ ಆತನಲ್ಲಿ ಸ್ತ್ರೀಯಲ್ಲಿರುವ ದೋಷವಾಗಲೀ, ಪುರುಷನಲ್ಲಿರುವ\nದೋಷವಾಗಲೀ ಇಲ್ಲ. ಆದ್ದರಿಂದ ಆತ ಲಿಂಗಾತೀತಕೂಡಾ ಹೌದು.[ಇದನ್ನು ನಾವು ಭಗವಂತನ\nನಾಮಾವಳಿಗಳಲ್ಲಿ ಕಾಣಬಹುದು].\nಭಗವಂತನೇ 'ಧಾತಾ'. ಆತ ಅನಾಧಿ ಅನಂತಕಾಲದಲ್ಲಿ ಈ ಜಗತ್ತಿನ ಧಾರಣೆ ಮತ್ತು ಪೋಷಣೆ ಮಾಡುವವ.\nಚತುರ್ಮುಖ ಬ್ರಹ್ಮನೊಳಗಿದ್ದು, ಪಿತಾಮಹ ಶಬ್ದ ವಾಚ್ಯನಾಗಿರುವವ ಭಗವಂತ.\nಇಲ್ಲಿ ಕೃಷ್ಣ ಕೇವಲ ಮುಖ್ಯವಾದ ಸಂಬಂಧವನ್ನು ಮಾತ್ರ ಹೇಳಿದ. ಇದರರ್ಥ ಎಲ್ಲಾ ಸಂಬಂಧದಲ್ಲಿಯೂ ಆ\nಭಾವವನ್ನು ಜಾಗೃತಗೊಳಿಸುವವ ಅಂತರ್ಯಾಮಿ ಭಗವಂತ ಎಂಬುದು. ಪ್ರತಿಯೊಂದು ಸಂಬಂಧದ ಹಿಂದೆ\nಭಗವಂತನ ಸಂಬಂಧವಿದೆ. ಆದರೆ ನಮಗೆ ಆ ಕಲ್ಪನೆ ಇರುವುದಿಲ್ಲ. ಆಯಾ ಜೀವದ ಪ್ರಾರಾಬ್ಧ\nಕರ್ಮಕ್ಕನುಗುಣವಾಗಿ ಸಂಬಂಧಗಳು. ಅಲ್ಲಿರುವ ಪ್ರೀತಿ, ಮಮತೆ, ಶತ್ರುತ್ವ ಎಲ್ಲವೂ ಭಗವಂತನ ಕಾರ್ಯಕ್ರಮ.\nಇದನ್ನು ನಾವು ತಿಳಿದಾಗ ನಮ್ಮ ಜೀವನ ಸುಗಮ. ಒಬ್ಬರು ನಮ್ಮನ್ನು ದ್ವೇಷಿಸಿದಾಗ ಕುಗ್ಗುವ ಅಗತ್ಯವಾಗಲೀ,\nಒಬ್ಬರು ನಮ್ಮನ್ನು ಪ್ರೀತಿಸಿದಾಗ ಹಿಗ್ಗುವ ಅಗತ್ಯವಾಗಲೀ ಇಲ್ಲ. ಎಲ್ಲವೂ ನಮ್ಮ ಜೀವಸ್ವಭಾವ ಮತ್ತು\nಪ್ರರಾಬ್ಬಕರ್ಮಕ್ಕನುಗುಣವಾಗಿ ಭಗವಂತನ ಲೀಲೆ ಎನ್ನು ವ ಎಚ್ಚರ ಇಲ್ಲಿ ಬಹಳ ಮುಖ್ಯ. ಇದಕ್ಕೆ ಒಂದು ಉತ್ತಮ\nದೃಷ್ಟಾಂತ ಭಾಗವತದಲ್ಲಿ ಬರುವ ವೃತ್ರ ಮತ್ತು ಇಂದ್ರನ ಯುದ್ಧದ ಕಥೆ: ಇಂದ್ರನನ್ನು ಕೊಲ್ಲಲು ಹೊರಟ\n'ವೃತ್ರ'ನ ತಂದೆ ತ್ವಸ್ಥ ಎಂಬುವನು ಉಚ್ಚರಿಸಿದ ಮಂತ್ರದಲ್ಲಿ ಒಂದು ಸ್ವರ ತಪ್ಪಾಗಿದ್ದರಿಂದ-ವೃತ್ರನಿಂದ\nಇಂದ್ರಹತ್ಯೆಯಾಗುವ ಬದಲು, ಇಂದ್ರನೇ ವೃತ್ರನನ್ನು ಕೊಲ್ಲುವಂತಾಯಿತು. ವೃತ್ರ ಮತ್ತು ಇಂದ್ರರ ಯುದ್ಧದಲ್ಲಿ\nಇಂದ್ರ ಮಹಾಜ್ಞಾನಿಯಾದ ವೃತ್ರನನ್ನು ಕೊಲ್ಲಲು ಹಿಂದೇಟು ಹಾಕುತ್ತಾನೆ. ಆಗ ವೃತ್ರ ಹೇಳುತ್ತಾನೆ: “ಸಂಕೋಚ\nಪಡಬೇಡ ಇಂದ್ರ, ನನ್ನನ್ನು ಕೊಂದುಬಿಡು. ಏಕೆಂದರೆ ಈ ನಾಟಕದಲ್ಲಿ ಭಗವಂತ ನಿನಗೆ ಕೊಲ್ಲುವ ಪಾತ್ರವನ್ನೂ\nಮತ್ತು ನನಗೆ ಸಾಯುವ ಪಾತ್ರವನ್ನೂ ಕೊಟ್ಟಿದ್ದಾನೆ. ನಾವು ಅದನ್ನು ಅಭಿನಯಿಸಬೇಕು ಅಷ್ಟೇ” ಎಂದು. ಈ ರೀತಿ\n\nಎಚ್ಚ ರವಿದ್ದರೆ ನಮಗೆ ಇನ್ನೊ ಬ್ಬರು ಬೈದಾಗ ಅಥವಾ ದ್ವೇಷಿಸಿದಾಗ ಬೇಸರವಾಗುವುದಿಲ್ಲ. ಎಲ್ಲವೂ ಭಗವಂತನ\nವ್ಯವಸ್ಥೆ ಎಂದು ತಿಳಿದಾಗ ಎಲ್ಲವೂ ಏಕರೂಪವಾಗಿ ಕಾಣುತ್ತದೆ. ದ್ವೇಷ ಮತ್ತು ಪ್ರೀತಿ ಸಹಜವಾಗಿ ಬಿಡುತ್ತದೆ.\nಸಂಬಂಧ ಕಳಚಿದಾಗ ಕುಗ್ಗುವುದಾಗಲೀ, ಬೆಸೆದಾಗ ಹಿಗ್ಗುವುದಾಗಲೀ ಇರುವುದಿಲ್ಲ. ಇದು ಬಹಳ ಎತ್ತರದ ಸ್ಥಿತಿ.\nಒಟ್ಟಿನಲ್ಲಿ ಕೃಷ್ಣ ಇಲ್ಲಿ ಹೇಳಿರುವ ವಿಚಾರವೆಂದರೆ: ಎಲ್ಲಾ ಸಂಬಂಧದ ಹಿಂದೆ ಇರುವವನು ಆ ಭಗವಂತ. ಎಲ್ಲರ\nಒಳಗೂ 'ಎಲ್ಲರೂ' ಆಗಿ ಆತ ತುಂಬಿದ್ದಾನೆ. ಒಂದೊಂದು ರೂಪದಲ್ಲಿ, ಅವರವರಲ್ಲಿ, ಆಯಾ ಕ್ರಿಯೆಗಳನ್ನು\nಮಾಡಿಸುತ್ತಾನೆ. ಇದು ನಾವು ಅನುಸಂಧಾನ ಮಾಡಬೇಕಾದ ವಿಜ್ಞಾನ.\n\nಕ್ರಿಯೆ, ಸಂಬಂಧಗಳನ್ನು ವಿವರಿಸಿದ ಕೃಷ್ಣ ಈಗ ಜ್ಞಾನದ ಬಗ್ಗೆ ವಿವರಿಸುತ್ತಾನೆ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ವೇದ್ಯಂ\nಪವಿತ್ರಮೋಂಕಾರ ಋಕ್ ಸಾಮ ಯಜುರೇವ ಚ” ಎಂದು. ನಾಮಾತ್ಮಕವಾದ ಈ ಪ್ರಪಂಚದ ಎಲ್ಲಾ ನಾಮಗಳ\nಮೂಲ 'ಓಂ'. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ನಾನು ಓಂಕಾರ” ಎಂದು. ಪ್ರಪಂಚದಲ್ಲಿನ ಎಲ್ಲಾ ಶಬ್ದವೂ ಹುಟ್ಟಿದ್ದು\nಓಂಕಾರದಿಂದ. ಆದ್ದರಿಂದ ಭಗವಂತ ಸರ್ವಶಬ್ದವಾಚ್ಯ. ಸಂಸ್ಕೃತದಲ್ಲಿನ ಎಲ್ಲಾ ಶಬ್ದಗಳೂ ಕೂಡಾ\nಓಂಕಾರದಿಂದ ಆವಿರ್ಬಾವಗೊಂಡ ಶಬ್ದಗಳು. ಅದು ಹೇಗೆಂದು ಸಂಕ್ಷಿಪ್ತವಾಗಿ ನೋಡೋಣ:\n\nವೈದಿಕವಾಜ್ಕಯದ ಮೂಲಾಕ್ಷರವಾದ ಓಂಕಾರದಲ್ಲಿ ಎಂಟು ಅಕ್ಷರಗಳು: ಅಕಾರ, ಉಕಾರ, ಮಕಾರ, ನಾದ,\nಬಿಂದು, ಕಲೆ, ಶಾಂತ, ಅತಿಶಾಂತ. ಇದರಿಂದ ವ್ಯಕ್ತವಾದದ್ದು ನಾರಾಯಣ ಅಷ್ಟಾ ಕ್ಷರ: \"ಓಂ ನಮೋ\nನಾರಾಯಣಾಯಃ'... ಓಂಕಾರದ ಎಂಟು ಮೂಲವರ್ಣಗಳಿಂದ ಅಕ್ಷರ ಮಾಲಿಕೆಯ ಎಂಟು ವರ್ಗಗಳು\nರೂಪುಗೊಂಡವು:\n\n೧. ಸ್ವರಾಕ್ಷರಗಳು: ಅ ಆ ಇ ಈ ಉ ಊ ಋ ೠ ಌ ೡ ಏ ಐ ಓ ಔ ಅಂ ಅಃ\n\n೨. ಕ-ವರ್ಗ: ಕ ಖ ಗ ಘ ಙ\n\n೩. ಚ-ವರ್ಗ: ಚ ಛ ಜ ಝ ಞ\n\n೪. ಟ-ವರ್ಗ: ಟ ಠ ಡ ಢ ಣ\n\n೫. ತ-ವರ್ಗ: ತ ಥ ದ ಧ ನ\n\n೬. ಪ-ವರ್ಗ:ಪಫಬಭಮ\n\n೭. ಅಂತಸ್ಥಾಕ್ಷರಗಳು: ಯ ರ ಲ ವ\n\n೮. ಕೊನೆಯ ಆರು ಅಕ್ಷರಗಳು: ಶ ಷ ಸ ಹ ಳ ಕ್ಷ\n\nಒಟ್ಟು 'ಅ' ದಿಂದ 'ಕ್ಷ' ತನಕ ಐವತ್ತೊಂದು ಅಕ್ಷರಗಳು(ಅ ದಿಂದ ಕ್ಷ ತನಕ ಆದ್ದರಿಂದ ಅ-ಕ್ಷ-ರ). ಇಡೀ\nಪ್ರಪಂಚದಲ್ಲಿರುವ ಎಲ್ಲಾ ಶಬ್ದಗಳೂ ಈ ಅಕ್ಷರಗಳ ಸಂಯೋಜನೆ. ಎಲ್ಲಾ ಶಬ್ದಗಳೂ ಓಂಕಾರದಿಂದ\nಹುಟ್ಟಿರುವುದರಿಂದ ಓಂಕಾರ ವಾಚ್ಯ ಭಗವಂತ ಸರ್ವಶಬ್ದ ವಾಚ್ಯ. ಆದ್ದರಿಂದ ಎಲ್ಲಾ ಶಬ್ದಗಳ ಮೂಲಭೂತ\nಪವಿತ್ರ ಅರ್ಥ ಭಗವಂತನನ್ನು ಹೇಳುತ್ತದೆ. ದೋಷವನ್ನು ಹೇಳುವ ಪದಗಳೂ ಕೂಡಾ ಭಗವಂತನಲ್ಲಿ ಕೇವಲ\nಪವಿತ್ರ ಅರ್ಥವನ್ನು ಮಾತ್ರ ಹೇಳುತ್ತವೆ. ಉದಾಹರಣೆಗೆ ದುಃಖಿ. ಇದು ಭಗವಂತನಲ್ಲಿ ಹೇಳುವಾಗ “ದುಃಖದ\nಒಡೆಯ ಎನ್ನುವ ಅರ್ಥವನ್ನು ಕೊಡುತ್ತದೆ.\n\nಐವತ್ತೊಂದು ಅಕ್ಷರಗಳಿಂದ(ಮಾತೃಕೆಗಳಿಂದ) ವಾಚ್ಯನಾದ ಭಗವಂತನ ರೂಪಗಳೂ ಐವತ್ತೊಂದು:\n\n೧. ಅಜ, ೨. ಆನಂದ, ೩. ಇಂದ್ರ, ೪. ಈಶ, ೫. ಉಗ್ರ, ೬. ಊರ್ಜ, ೭. ಋತಂಭರ, ೮. ೠಘ, ೯. ಌಶ, ೧೦. ೡಜಿ, ೧೧. ಏಕಾತ್ಮ, ೧೨. ಐರ, ೧೩. ಓಜೋಭೃತ್‌, ೧೪. ಔರಸ, ೧೫. ಅಂತ, ೧೬. ಅರ್ಧಗರ್ಭ, ೧೭. ಕಪಿಲ, ೧೮. ಖಪತಿ, ೧೯. ಗರುಡಾಸನ, ೨೦. ಘರ್ಮ, ೨೧. ಙಸಾರ, ೨೨. ಚಾರ್ವಾಂಗ, ೨೩. ಛಂದೋಗಮ್ಯ, ೨೪. ಜನಾರ್ದನ, ೨೫. ಝೂಟಿತಾರಿ, ೨೬. ಞಮ, ೨೭. ಟಂಕಿ, ೨೮. ಠಕಲ, ೨೯. ಡರಕ, ೩೦. ಢರಿ, ೩೧. ಣಾತ್ಮ, ೩೨. ತಾರ, ೩೩. ಥಭ, ೩೪. ದಂಡಿ, ೩೫. ಧನ್ವಿ, ೩೬. ನಮ್ಯ, ೩೭. ಪರ, ೩೮. ಫಲಿ, ೩೯. ಬಲಿ, ೪೦. ಭಗ, ೪೧. ಮನು, ೪೨. ಯಜ್ಞ, ೪೩. ರಾಮ, ೪೪. ಲಕ್ಷ್ಮೀಪತಿ, ೪೫. ವರ, ೪೬. ಶಾಂತಸಂವಿತ್‌, ೪೭. ಷಡ್ಗುಣ, ೪೮. ಸಾರಾತ್ಮ, ೪೯. ಹಂಸ, ೫೦. ಳಾಳುಕ, ೫೧. ನೃಸಿಂಹ [ನೃಹರ್ಯಕ್ಷ].\n\nಓಂಕಾರದ ಮೂಲ ಮೂರಕ್ಷರ ಅ-ಉ-ಮ ಪದ್ಯ-ಗದ್ಯ-ಗಾನ. ಇದು ಮೂರು ರೂಪದ ವೇದವನ್ನು ಮತ್ತು ವೇದ\nಪ್ರತಿಪಾದ್ಯ ಭಗವಂತನನ್ನು ಹೇಳುತ್ತವೆ. 'ಅ'ಕಾರ ಋಗ್ವೇದಕ್ಕೆ, \"ಉ'ಕಾರ ಯಜುರ್ವೇದಕ್ಕೆ ಮತ್ತು \"ಮ'ಕಾರ\nಸಾಮವೇದಕ್ಕೆ ಸಂಬಂಧಪಟ್ಟದ್ದು. ಋಗ್ವೇದ \" ಅಗ್ನಿಮೀಳೇ ಪುರೋಹಿತಂ ಯಜ್ಞಸ್ಯ ದೇವಮೃತ್ವಿಜಂ” |\nಹೋತಾರಂ ರತ್ನ ಧಾತಮಂ |...” ಎಂದು “ಅ' ಕಾರದಿಂದ ಪ್ರಾರಂಭವಾಗುತ್ತದೆ. ಮತ್ತು “...ಸಮಾನಮಸ್ತು\nವೋ ಮನೋ ಯಥಾ ವಃ ಸುಸಹಾಸತಿ ॥” ಎಂದು 'ಇ'ಕಾರದಲ್ಲಿ ಕೊನೆಗೊಳ್ಳುತ್ತದೆ. ಅಲ್ಲಿಂದ ಮುಂದುವರಿದು\nಯಜುರ್ವೇದ “ಇಷೇ ತ್ವೋರ್ಜೆ ತ್ವಾ ..” ಎಂದು “ಇ'ಕಾರದಿಂದ ಪ್ರಾರಂಭವಾಗಿ “.......ಸಮುದ್ರೋ ಬಂಧು”\nಎಂದು \"ಉ'ಕಾರದಲ್ಲಿ ಕೊನೆಗೊಳ್ಳುತ್ತದೆ. ಹೀಗೆ ಓಂಕಾರದಲ್ಲಿನ “ಅ'ಕಾರ ಮತ್ತು \"ಉ'ಕಾರ ಋಗ್ವೇದ ಮತ್ತು\nಯಜುರ್ವೇದವನ್ನು ಪೂರ್ಣವಾಗಿ ಸೂಚಿಸುವ ಸಂಕ್ಷೇಪಣಾ(abbreviation)ರೂಪ. ಇಲ್ಲಿಂದ ಮುಂದೆ\nಸಾಮವೇದ. ಸಾಮವೇದ “ಅಗ್ನ ಆ ಯಾಹಿ ...” ಎಂದು 'ಅ'ಕಾರದಿಂದ ಆರಂಭವಾಗಿ\n“ಸ್ವಸ್ತಿನೋ ಬೃಹಸ್ಪತಿರ್ದಧಾತು” ಎಂದು \"ಉ'ಕಾರದಲ್ಲಿ ಕೊನೆಗೊಳ್ಳುತ್ತದೆ. ಆದ್ದರಿಂದ ಇಲ್ಲಿ 'ಮ' ಕಾರ ಬಂದಿಲ್ಲ. ಆದರೆ\nನಮಗೆ ತಿಳಿದಂತೆ ಸಾಮವೇದ ನಾದ ರೂಪದಲ್ಲಿದೆ. ಓಂಕಾರದಲ್ಲಿ ಕೂಡಾ \"ಮ' ಎನ್ನುವುದು ನಾದರೂಪದಲ್ಲಿ\nಹೊರ ಹೊಮ್ಮುವ ಅಕ್ಷರ- ಅದು ಸಂಗೀತ. ಹೀಗೆ ಓಂಕಾರ ವೇದದ ಸಂಕ್ಷೇಪಣಾರೂಪ ಬೀಜಾಕ್ಷರ. ಇದು ನಮಗೆ\nವೇದವನ್ನು ಗುರುತಿಸುವ ಮಾರ್ಗದರ್ಶಿ. ಆದ್ದರಿಂದ ಓಂಕಾರ ಭಗವಂತನನ್ನು ಸ್ತೋತ್ರ ಮಾಡುವ ಮಂತ್ರಗಳಲ್ಲಿ\nಅತ್ಯಂತ ಪ್ರಕೃಷ್ಣವಾದುದ್ದು. ಇದಕ್ಕಿಂತ ದೊಡ್ಡ ಸ್ತೋತ್ರಮಾಡುವ ಶಬ್ದ ಈ ಪ್ರಪಂಚದಲ್ಲಿಲ್ಲ. ಈ ಕಾರಣದಿಂದ\nಓಂಕಾರ ಭಗವಂತನನ್ನು ನಾವು ಕರೆಯಲು ಬಳಸುವ ಅವನ ವಿಶೇಷ(Exclusive) ನಾಮ.\n\nಓಂಕಾರ ವಿಸ್ಪತವಾದಾಗ ವ್ಯಾಹೃತಿ, ವ್ಯಾಹೃತಿ ವಿಸ್ತಾರವಾಗಿ ಗಾಯತ್ರಿ, ಗಾಯತ್ರಿ ವಿಸ್ತಾರವಾಗಿ ಕುರುಡ\nಸೂಕ್ತ, ನಂತರ ಮೂರು ವೇದಗಳು, ಅಲ್ಲಿಂದ ಸಮಸ್ತ ವೇದಗಳು. ಹೀಗೆ ಪ್ರಣವದಲ್ಲಿ, ವ್ಯಾಹೃತಿಯಲ್ಲಿ, ಪುರುಷ\nಸೂಕ್ತದಲ್ಲಿ, ಸಮಸ್ತವೇದಗಳಲ್ಲಿ ಭಗವಂತ ನೆಲೆಸಿದ್ದಾನೆ. ಓಂಕಾರದ ಬಗ್ಗೆ ಇನ್ನೂ ಅನೇಕ ವಿವರಗಳನ್ನು\nಈಗಾಗಲೇ ಅಧ್ಯಾಯ ಏಳರಲ್ಲಿಶ್ಲೋಕ -೦೮) ವಿಶೇಷವಾಗಿ ವಿವರಿಸಲಾಗಿದೆ.\n\nವೇದದ ಶಬ್ದಗಳಿಂದಲೇ ಹುಟ್ಟಿ ಬಂದ ಪ್ರಪಂಚದ ಎಲ್ಲಾ ಶಬ್ದದಲ್ಲೂ ಎಲ್ಲಾ ಲೌಕಿಕ ನಾದದಲ್ಲೂ ತುಂಬಿದ\nಭಗವಂತ, ಆಕಾಶದಲ್ಲಿ ಅನಂತ ಶಬ್ದಗಳನ್ನೂ, ಅನಂತ ನಾದಗಳನ್ನೂ ಸೃಷ್ಟಿ ಮಾಡಿದ. ನಮಗೆ ಶಬ್ದದಿಂದ\nಅನಂತ ಅನುಭವವನ್ನು ಕೊಟ್ಟು, ಆ ಶಬ್ದವನ್ನು ಗ್ರಹಿಸುವ ಮತ್ತು ಗ್ರಹಿಸಿ ಪುನರುಚ್ಛರಿಸುವ ವಿಶೇಷ ಶಕ್ತಿಯನ್ನು\nಕರುಣಿಸಿದ. ಜ್ಞಾನದ ಮೂಲಕ ಈ ಶಬ್ದ ನಾಮಕ ಭಗವಂತನನ್ನು ತಿಳಿಯುವ ವಿಶೇಷ ಶಕ್ತಿ ಮಾನವನಿಗೆ\nಭಗವಂತನ ವಿಶೇಷ ಕೊಡುಗೆ.\n\nಭಗವಂತ 'ಋಕ್': ಯಾವುದರಿಂದ ನಾವು ಭಗವಂತನನ್ನು ಅರ್ಚನೆ ಮಾಡುತ್ತೇವೋ ಅದು ಋಕ್. ನಾವು\nಅರ್ಚನೆ ಮಾಡುವುದು ಮಂತ್ರಗಳ ಮೂಲಕ. ಯಾರು ಅರ್ಚಿಸಲ್ಪಡುತ್ತಾನೋ ಅವನು 'ಋಕ್' ನಾಮಕ\nಭಗವಂತ. ಎಲ್ಲಾ ಮಂತ್ರಗಳಿಂದ ಅರ್ಚಿಸಲ್ಪಡುವವ.-ಸ್ತುತಿಗೆ ಪಾತ್ರನಾದ ಭಗವಂತ 'ಋಕ್'\n\nಭಗವಂತ “ಸಾಮಃ': ಎಲ್ಲವನ್ನು ಸಮೀಕರಿಸಿದವನು. ತನ್ನ ಎಲ್ಲಾ ರೂಪದಲ್ಲಿ ಜ್ಞಾನಾನಂದಾದಿ ಗುಣಗಳಿಂದ\nಸಮನಾದ್ದರಿಂದ ಮತ್ತು ಅವರವರ ಯೋಗ್ಯತೆಗೆ ಸಮನಾಗಿ ಜೀವನ ಕೊಡುವ ಭಗವಂತ “ಸಾಮಃ'.\n\nಭಗವಂತ “ಯಜುಸ್‌: ಎಲ್ಲಾ ಯಾಗಗಳಿಂದ ಹೋಮಿಸಲ್ಪಡುವ, ವೇದಗಳಲ್ಲಿ ಸನ್ನಿಹಿತನಾಗಿರುವ\nಸರ್ವಶಬ್ದವಾಚ್ಯ ಭಗವಂತ “ಯಜುಸ್‌”,\n",
  "9.18": "ಗತಿಃ ಭರ್ತಾ ಪ್ರಭುಃ ಸಾಕ್ಷೀ ನಿವಾಸಃ ಶರಣಮ್‌ ಸುಹೃತ್‌ ।\n\nಪ್ರಭವಃ ಪ್ರಳಯಃ ಸ್ಥಾನಮ್‌ ನಿಧಾನಮ್‌ ಬೀಜಮ್‌ ಅವ್ಯಯಮ್‌-ಮುಕ್ತಿಗಾಗಿ ತಿಳಿಯಬೇಕಾದವನು. ಎಲ್ಲಾ\nಹೊಣೆಯನ್ನು ಹೊತ್ತವನು. ಎಲ್ಲದರ ಒಡೆಯ. ಎಲ್ಲವನ್ನು ನೇರ ಕಾಣಬಲ್ಲವನು. ಎಲ್ಲರ ನೆಲೆ. ಮುಕ್ತರಿಗೂ ಆಸರೆ.\nಅನಿಮಿತ್ತ ಬಂಧು. ಸೃಷ್ಟಿ-ಸ್ಥಿತಿ-ಪ್ರಳಯಗಳಿಗೆ ಕಾರಣ. ಪ್ರಳಯದಲ್ಲಿ ಜಗವನ್ನು ಬಸಿರಲ್ಲಿ ಹೊತ್ತವನು. ಮತ್ತೆ ಜಗದ\nಅಭಿವ್ಯಕ್ತಿಗೆ ಕಾರಣನಾದವನು. ಅಳಿವಿರದವನು.\n\nಸಂಬಂಧಗಳ ಬಗ್ಗೆ ಹಿಂದೆ ಹೇಳಿದ್ದ ಕೃಷ್ಣ ಇಲ್ಲಿ ನಾನಾ ವಿಧದ ಅನುಬಂಧಗಳನ್ನು ಹೇಳುತ್ತಾನೆ. ಬೇರೆಬೇರೆ\nರೀತಿಯಾಗಿ ಸಮಾಜದಲ್ಲಿ ಒಬ್ಬರಿಂದ ಒಬ್ಬರು ನೆರವು ಪಡೆಯುತ್ತಾರೆ. ರಾಜನಿಂದ ರಕ್ಷಣೆ, ಆಪತ್ಕಾಲದಲ್ಲಿ\nಆಶ್ರಯ, ಕಷ್ಟದಲ್ಲಿರುವವನನ್ನು ಸಂತೈಸುವುದು, ಗೆಳೆತನ ಇತ್ಯಾದಿ ಅನುಬಂಧಗಳು. ಇವೆಲ್ಲವೂ ಭಗವಂತನ\nಧರ್ಮ ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.\nಯಾರೂ ನೆಲೆಯೇ ಇಲ್ಲ, ಬದುಕುವುದಕ್ಕೆ ಅವಕಾಶವೇ ಇಲ್ಲ ಅನ್ನು ವಾಗ \"ನಾನಿದ್ದೇನೆ' ಎಂದು ರಕ್ಷಣೆ\nಮಾಡುವವರನ್ನು 'ಗತಿ' ಎನ್ನುತ್ತಾರೆ. ವಾಸ್ತವವಾಗಿ ಗತಿ ಎಂದರೆ ಕೊನೆಯ ಗತಿ. ಸಂಸಾರದಲ್ಲಿ ಮಾತ್ರ ಅಲ್ಲ\nಮೋಕ್ಷದಲ್ಲೂ ಆಶ್ರಯವಾಗಿರುವ ಭಗವಂತ ಗತಿಃ, ಆತನೇ ಸದ್ಗತಿ, ತಪ್ಪು ಮಾಡಿದಾಗ ಆತನೇ ದುರ್ಗತಿ\nಕೂಡಾ. ಎಲ್ಲಾ ಹೊಣೆಯನ್ನೂ ಹೊತ್ತು, ಪ್ರಪಂಚದಲ್ಲಿ ಪ್ರತಿಯೊಬ್ಬರೂ ಏನು ಮಾಡುತ್ತಾರೆ, ಅವರ ಒಳಿತು\nಕೆಡುಕುಗಳೇನು ಎಂದು ನೋಡಬಲ್ಲ ಪ್ರಭು ಭಗವಂತ. ಆತ ನಮ್ಮ ಅಂತರಂಗ ಬಹಿರಂಗ ಎಲ್ಲವನ್ನೂ ಬಲ್ಲವ.\nಆತ ಎಲ್ಲೆಡೆ ತುಂಬಿ ಎಲ್ಲವನ್ನೂ ಕಾಣಬಲ್ಲ ನಿಜವಾದ ಸಾಕ್ಷಿ.\nಮುಂದುವರಿದು ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ಅಹಮ್‌ ನಿವಾಸಃ” ಎಂದು. ಈಶಾವಾಸ್ಯೋಪನಿಷತ್ತಿನಲ್ಲಿ ಹೇಳುವಂತೆ:\nಈಶಾವಾಸ್ಯಂ ಇದಂ ಸರ್ವಂ ಯತ್‌ ಕಿಂಚ ಜಗತ್ಯಾಂ ಜಗತ್‌ |\nತೇನ ತ್ಯಕ್ಷೇನ ಭೂಂಜಿಥಾಃ ಮಾ ಗೃಧಃ ಕಸ್ಯ ಸ್ವಿದ್‌ ಧನಮ್‌]\n\nನಾವು ವಾಸ ಮಾಡುತ್ತಿರುವುದೇ ಭಗವಂತನ ಮನೆಯಲ್ಲಿ. ಈ ವಿಶ್ವವೆಂಬ ಮನೆಯನ್ನು ನಿರ್ಮಿಸಿ, ಅದರಲ್ಲಿ\nನಮಗೆ ಆಶ್ರಯ ಕೊಟ್ಟು, ನಮಗೆ ಬದುಕಲು ಬೇಕಾದ ವ್ಯವಸ್ಥೆ ಮಾಡಿದ ಭಗವಂತ ನಿವಾಸಃ. ಆತ ಎಲ್ಲರಿಗೂ\nಆಸರೆ. ಇಂತಹ ಭಗವಂತ ನಮಗೆ ಆಪತ್ಕಾಲದಲ್ಲಿ ರಕ್ಷಣೆ(ಶರಣ) ಕೊಡುವ ಆತ್ಮೀಯ ಗೆಳೆಯ(ಸುಹೃತ್‌).\nಗೆಳೆಯರಲ್ಲಿ ಎರಡು ವಿಧ. ಸಖ ಮತ್ತು ಸುಹೃತ್‌. 'ಸಖ' ಎಂದರೆ ಒಡನಾಡಿ. ಯಾವಾಗಲೂ ಜೊತೆಗಿರುವವ.\nಸುಹೃತ್‌ ಎಂದರೆ ದೂರದಲ್ಲಿರಲೀ ಹತ್ತಿರವಿರಲೀ ನಮ್ಮ ಹೃದಯಕ್ಕೆ ಸ್ಪಂದಿಸಿ ನಮ್ಮ ಹಿತಚಿಂತಕನಾಗಿರುವವ.\nಭಗವಂತ ನಮ್ಮ ಹೃತ್ಕಮಲಮಧ್ಯ ನಿವಾಸಿಯಾಗಿರುವ ಸಖ ಮತ್ತು ನಮ್ಮ ಹೃದಯದ ಕಾಗಿಗೆ ಸದಾ\nಸ್ಪಂದಿಸುವ ಸುಹೃತ್‌.\n\nಅನುಬಂಧವನ್ನು ಹೇಳಿದ ಕೃಷ್ಣ ಮುಂದೆ ಮನುಷ್ಯ ಶಕ್ತಿಯನ್ನು ಬಿಟ್ಟು ದೇವತಾ ಶಕ್ತಿಯನ್ನು ವಿವರಿಸುತ್ತಾನೆ.\nಹೇಳುತ್ತಾನೆ “ಪ್ರಭವಃ ಪ್ರಳಯಃ ಸ್ಥಾನಂ ನಿಧಾನಂ ಬೀಜಮವ್ಯಯಮ್‌” ಎಂದು. ನಮ್ಮಲ್ಟಿ ಕೆಲವರು ತಿಳಿದಿದ್ದಾರೆ\nಸೃಷ್ಟಿಕರ್ತ -ಬ್ರಹ್ಮ, ಸ್ಥಿತಿ-ವಿಷ್ಣು ಮತ್ತು ಸಂಹಾರ-ಶಿವ ಎಂದು. ಇಲ್ಲಿ ಕೃಷ್ಣ ಸ್ಪಷ್ಟವಾಗಿ ಹೇಳುತ್ತಾನೆ: “ನಾನೇ\nಪ್ರಭವಃ- ಪ್ರಳಯಃ-ಸ್ಥಾನಂ” ಎಂದು. ಜಗತ್ತಿನ ಸೃಷ್ಟಿಗೆ ಮೂಲ ಕಾರಣ-ಭಗವಂತ. ಸೃಷ್ಟಿಯ ಕೊನೆಯಲ್ಲಿ ಈ\nಜಗತ್ತು ನಾಶವಾಗಲು, ಮತ್ತು ಸೃಷ್ಟಿಯಿಂದ ಸಂಹಾರ ತನಕದ ಅವದಿಯಲ್ಲಿ ಸ್ಥಿತಿಗೆ ಮೂಲತಃ ಭಗವಂತನೇ\nಕಾರಣ.\n\nಪ್ರಳಯ ಕಾಲದಲ್ಲಿ ಸಮಸ್ತ ಜೀವಜಾತವನ್ನು ಸೂಕ್ಷ್ಮ ಸ್ಥಿತಿಯಲ್ಲಿ ತನ್ನ ಹೊಟ್ಟೆಯಲ್ಲಿಟ್ಟು ಸಾಕುವವ ಆ ಭಗವಂತ.\nಆ ಸೂಕ್ಷ್ಮ ವಸ್ತು ಮತ್ತೆ ಚಿಗುರಿ ಅರಳಿ ಹೆಮ್ಮರವಾಗಿ ಬೆಳೆಯುವಂತೆ ಬೀಜಕ್ಷೇಪ ಮಾಡುವ, ಎಂದೂ ಅಳಿವಿಲ್ಲದ\nಅವ್ಯಯ-ಭಗವಂತ.\n\nಹೀಗೆ ಜಗತ್ತಿನ ಸಮಸ್ತ ಕ್ರಿಯೆಯನ್ನು, ಲೌಕಿಕ , ಪ್ರಾಪಂಚಿಕ, ಪಾರಲೌಕಿಕ, ಸಂಬಂಧಗಳು, ಅನುಬಂಧಗಳು\nಎಲ್ಲವನ್ನೂ ವಿವರಿಸಿದ ಕೃಷ್ಣ ಮುಂದೆ ಕಾಲಕಾಲದಲ್ಲಿ ಆಗತಕ್ಕಂತಹ ಸಂಗತಿಗಳನ್ನು ವಿವರಿಸುತ್ತಾನೆ.",
  "9.19": "ತಪಾಮಿ ಅಹಮ್‌ ಅಹಮ್‌ ವರ್ಷಮ್‌ ನಿಗೃಹ್ಣಾಮಿ ಉತ್ಸೃಜಾಮಿ ಚ ।\n\nಅಮೃತಮ್‌ ಚ ಏವ ಮೃತ್ಯುಃ ಚ ಸತ್‌ ಅಸತ್‌ ಚ ಅಹಮ್‌ ಅರ್ಜುನ-ನಾನು ಸುಡುತ್ತೇನೆ. ನಾನು ಮಳೆ ಬರದಂತೆ ತಡೆಯುತ್ತೇನೆ; ಮಳೆಗರೆಸುತ್ತೇನೆ. ಸಾವು ಬರದಂತೆ ಮಾಡುತ್ತೇನೆ; ಸಾಯಿಸುತ್ತೇನೆ. ಓ ಅರ್ಜುನಾ, ಕಾಣುವ ಕಾರ್ಯ, ಕಾಣದ ಕಾರಣ ಎಲ್ಲವೂ ನನ್ನಿಂದ.[ಸದ್ಗುಣಗಳ ಸೆಲೆಯಾದ್ದರಿಂದ ನಾನು 'ಸತ್‌'. ನನ್ನಂಥವ ಇನ್ನೊಬ್ಬ ಇರದ್ದರಿಂದ ನಾನು 'ಅಸತ್‌']\n\nಸೂರ್ಯನಲ್ಲಿ ಸನ್ನಿಹಿತನಾಗಿ, ಭೂಮಿಗೆ ಸೌರಶಕ್ತಿಯನ್ನು ಹರಿಸಿ, ಬದುಕು ಕೊಟ್ಟವ ಭಗವಂತ. ಕಾಲ ಕಾಲಕ್ಕೆ ಮಳೆ ಬರುವಂತೆ ಮಾಡುವವನೂ ಅವನೇ; ಅಕಾಲದಲ್ಲಿ ಮಳೆ ಬಾರದಂತೆ ತಡೆಯುವವನೂ ಅವನೇ. ಮಳೆ ಬರಬೇಕಾದಾಗ ಬಾರದೇ ಇರುವುದು, ಮಳೆ ಬರಬಾರದಾಗ ಬರುವುದೂ ಭಗವಂತನಿಂದಲೇ. ಕಾಣುವ ಕ್ರಿಯೆಯ ಹಿಂದಿನ ಕಾರಣಶಕ್ತಿ ಭಗವಂತ.\n\nಭಗವಂತ ನಮ್ಮ ಬದುಕಿನಲ್ಲಿ ಉಸಿರು ಕೊಟ್ಟು ಬದುಕಿಸುವ ಅಮೃತ. ಆಯುಸ್ಸು ಮುಗಿದಾಗ ಉಸಿರು ನಿಲ್ಲಿಸಿ ಕರೆಸಿ ಕೊಳ್ಳುವವನೂ ಅವನೇ. ಒಟ್ಟಿನಲ್ಲಿ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ಕಣ್ಣಿಗೆ ಕಾಣುವ (ಸತ್‌), ಕಣ್ಣಿಗೆ ಕಾಣದ (ಅಸತ್‌) ಸಮಸ್ತ ಪ್ರಪಂಚವನ್ನು ನಿರ್ವಹಿಸುವ ಶಕ್ತಿ ನಾನು” ಎಂದು. ಇದು ಕೃಷ್ಣ ಸೂಕ್ಷ್ಮವಾಗಿ ಭಗವಂತನ ಅನುಸಂಧಾನಕ್ಕೆ ಕೊಟ್ಟಿರುವ ಸಮಗ್ರ ಚಿತ್ರಣ. ಇಲ್ಲಿ ಪೂರ್ಣ ಪ್ರಮಾಣದಲ್ಲಿ ಭಗವಂತನ ಅನುಸಂಧಾನಕ್ಕೆ ಬೇಕಾದ ಸಮಗ್ರ ಸಂಗತಿ ಅಡಗಿದೆ.\n\nಮುಂದೆ ಕೃಷ್ಣ ತನ್ನ ಭಕ್ತರಲ್ಲಿ(ಜ್ಞಾನಿಗಳಲ್ಲಿ) ಪ್ರಮುಖವಾಗಿ ಎರಡು ವಿಧದ ಭಕ್ತರ ಬಗ್ಗೆ ವಿವರಿಸುತ್ತಾನೆ. ಅವರೆಂದರೆ ತ್ರೈವಿದ್ಯರು ಮತ್ತು ಭಾಗವತರು.",
  "9.20": "ತ್ರೈವಿದ್ಯಾಃ ಮಾಮ್‌ ಸೋಮಪಾಃ ಪೂತ ಪಾಪಾಃ ಯಜ್ಞೈಃ ಇಷ್ಟ್ವಾ ಸ್ವಃ ಗತಿಮ್‌ ಪ್ರಾರ್ಥಯಂತೇ | ತೇ ಪುಣ್ಯಮ್‌ ಆಸಾದ್ಯ ಸುರ ಇಂದ್ರ ಲೋಕಮ್‌ ಅಶ್ನಂತಿ ದಿವ್ಯಾನ್‌ ದಿವಿ ದೇವ ಭೋಗಾನ್‌ - ತ್ರೈವಿದ್ಯರು (ಮೂರು ವೇದಗಳ ಮೊರೆಹೊಕ್ಕ ಹಂಬಲಿಗರು) ಹೋಮಿಸುತ್ತಾ ನನ್ನನ್ನಾರಾಧಿಸಿ, ಸೋಮರಸ ಕುಡಿದು, ಪಾಪ ತೊಡೆದು, ಸಗ್ಗದ ದಾರಿಯನ್ನು ಬೇಡುತ್ತಾರೆ. ಅವರು ಪುಣ್ಯದ ಫಲವಾಗಿ ದೇವೇಂದ್ರನ ನಾಡು ಸೇರಿ, ಆ ಸಗ್ಗದಲ್ಲಿ ವೆಗ್ಗಳದ ದೇವಭೋಗಗಳನ್ನು ಉಣ್ಣುತ್ತಾರೆ.\n\nತ್ರೈವಿದ್ಯರು ಎಂದರೆ ತ್ರಿಪಥಗಾಮಿಗಳು! ಇವರು ಭಗವಂತನ ಜೊತೆಗೆ ಅನೇಕವನ್ನು ಹಂಚಿಕೊಂಡವರು. ಇವರು ಸ್ವರ್ಗದ ಬಯಕೆ, ಲೌಕಿಕ ಬಯಕೆಯನ್ನು ಮುಂದಿಟ್ಟು ಭಗವಂತನಲ್ಲಿ ಭಕ್ತಿ ಮಾಡುತ್ತಾರೆ. ಇವರಿಗೆ ವೇದದಲ್ಲಿ ಹೇಳಿದ ಕರ್ಮಖಂಡವೇ ಮುಖ್ಯವಾಗುತ್ತದೆ. ಜ್ಯೋತಿಷ್ಟೋಮಯ ಯಾಗದಂತಹ ಯಾಗವನ್ನು ಕೇವಲ ಸ್ವರ್ಗದ ಬಯಕೆಯಿಂದ ಮಾಡಿ, ಭಗವಂತನನ್ನು ಬಯಸದೆ ಸ್ವರ್ಗವನ್ನು ಬಯಸುತ್ತಾರೆ. ಹೀಗೆ ಭಕ್ತಿ ಮಾಡುವುದರ ಫಲವಾಗಿ ಅವರು ಇಂದ್ರನ ನಾಡಾದ ಸ್ವರ್ಗವನ್ನು ಸೇರಿ ಅಲ್ಲಿ ಭೋಗವನ್ನು ಅನುಭವಿಸುತ್ತಾರೆ.",
  "9.21": "ತೇ ತಮ್‌ ಭುಕ್ತ್ವಾ ಸ್ವರ್ಗ ಲೋಕಮ್‌ ವಿಶಾಲಮ್‌ ಕ್ಷೀಣೇ ಪುಣ್ಯೇ ಮರ್ತ್ಯ ಲೋಕಮ್‌ ವಿಶಂತಿ ।\nಏವಮ್‌ ತ್ರಯೀ ಧರ್ಮಮ್‌ ಅನುಪ್ರಪನ್ನಾಃ ಗತ ಆಗತಮ್‌ ಕಾಮ ಕಾಮಾ: ಲಭಂತೇ - ಅವರು ಹಿರಿದಾದ\n\nಸಗ್ಗಿಗರ ನಾಡನ್ನು ಕಂಡುಂಡು, ಪುಣ್ಯ ಮುಗಿದಾಗ ಭೂಮಿಗೆ ಮರಳುತ್ತಾರೆ. ಹೀಗೆ ವೈದಿಕ ಕರ್ಮಗಳ ಮೊರೆ\nಹೊಕ್ಕು, ಬಯಕೆಗಳ ಬೆನ್ನುಹತ್ತಿ ಅತ್ತಿಂದಿತ್ತ ಅಲೆದಾಡುತ್ತಿರುತ್ತಾರೆ.\n\nಸ್ವರ್ಗದ ಬಯಕೆಯಿಂದ ಪುಣ್ಯಕರ್ಮ ಮಾಡುವ ತ್ರೈವಿದ್ಯರು ಸ್ವರ್ಗವನ್ನು ಸೇರಿ ಅಲ್ಲಿ ಬಗೆ ಬಗೆಯ ಭೋಗವನ್ನು\nಅನುಭವಿಸಿ ತಮ್ಮ ಸತ್ಕರ್ಮದ ಫಲ ಮುಗಿದ ತಕ್ಷಣ ಪುನಃ ಭೂಲೋಕದಲ್ಲಿ ಹುಟ್ಟುತ್ತಾರೆ. ಈ ಕಾರಣದಿಂದ\nಇವರು ಅತ್ಯಂತ ಹಿರಿದಾದ ಮೋಕ್ಷದಿಂದ ಮತ್ತು ಭಗವಂತನಿಂದ. ವಂಚಿತರಾಗುತ್ತಾರೆ. ಇವರು ಸದಾ\nಬಯಕೆಗಳ ಬೆನ್ನು ಹತ್ತಿ ಚಕ್ರಭ್ರಮಣದಲ್ಲಿ ಸಿಲುಕಿ ಕೊಳ್ಳುತ್ತಾರೆ. ಇವರಿಗಿಂತ ತೀರ ಭಿನ್ನ ನಡೆ ಭಾಗವತರದ್ದು:\n",
  "9.22": "ಅನನ್ಯಾಃ ಚಿಂತಯಂತಃ ಮಾಮ್‌ ಯೇ ಜನಾಃ ಪರ್ಯುಪಾಸತೇ ।\n\nತೇಷಾಮ್‌ ನಿತ್ಯ ಅಭಿಯುಕ್ತಾನಾಮ್‌ ಯೋಗ ಕ್ಷೇಮಮ್‌ ವಹಾಮಿ ಅಹಮ್‌- ಬೇರೆಲ್ಲಾ ತೊರೆದು ನನ್ನನ್ನೇ\nನೆನೆಯುತ್ತಾ ಪರಿಪರಿಯಿಂದ ಪೂಜಿಸುವ ಜನರು ಎಲ್ಲೆಲ್ಲೂ ನನ್ನ ಸೇವೆಗೆ ಮುಡಿಪಾದವರು. ಅವರ ಯೋಗ-\nಕ್ಷೇಮದ ಹೊಣೆ ನನ್ನದು.\n\nಭಾಗವತರು ಯಾವುದನ್ನೂ ಬೇಕು ಎಂದು ಬಯಸುವುದಿಲ್ಲ. ಅವರಿಗೆ ಭಗವಂತನ ಚಿಂತನೆಯೊಂದನ್ನು ಬಿಟ್ಟರೆ\nಬೇರೆ ಚಿಂತನೆಯೇ ಇಲ್ಲ. ಇವರು ಅನನ್ಯವಾಗಿ ಭಗವಂತನನ್ನು ಮಾತ್ರ ಬಯಸುತ್ತಾರೆ. ಯಾವುದೋ ಬಯಕೆಗೆ\nಕಟ್ಟು ಬಿದ್ದು ಅವರು ಪೂಜೆ ಮಾಡುವುದಿಲ್ಲ. ಇವರು ಭಗವಂತನಲ್ಲದೆ ಇನ್ಯಾವುದೇ ದೇವತೆಯನ್ನು\nಪ್ರಧಾನವಾಗಿಟ್ಟುಕೊಂಡು ಆಹುತಿ ಕೊಟ್ಟು ಆರಾಧನೆ ಮಾಡುವುದಿಲ್ಲ. ಎಲ್ಲಾ ದೇವತೆಯ ಒಳಗೂ ಇವರು\nಕೇವಲ ಭಗವಂತನನ್ನು ಕಾಣುತ್ತಾರೆ. ಇದು ಏಕಭಕ್ತಿ; ಪರಮಾತ್ಮನನ್ನು, ಮೋಕ್ಷವನ್ನು ಸೇರಲು\nಅನುಸರಿಸಬೇಕಾದ ಮಾರ್ಗ.\n\nನಾವು ಪೂಜೆ ಮಾಡಿಸಿದಾಗ ಸಂಕಲ್ಪ ಮಾಡುತ್ತೇವೆ. ಇಲ್ಲಿ ನಾವು ಎಂದೂ ನಮ್ಮ ಐಹಿಕ ಬಯಕೆಗಳನ್ನು\nಭಗವಂತನ ಮುಂದಿಡಬಾರದು. ಕೇವಲ ಜ್ಞಾನ, ಭಕ್ತಿ, ಮೋಕ್ಷ- ಇದು ನಮ್ಮ ಸಂಕಲ್ಪವಾಗಿರಬೇಕು. ನಶ್ವರವಾದ\nಬಯಕೆಗಳನ್ನು ಮುಂದಿಟ್ಟು ಪೂಜೆ ಮಾಡಿಸಿದಾಗ ನಾವು ಮಹತ್ತಾದ ಫಲವನ್ನು ಕಳೆದುಕೊಳ್ಳುತ್ತೇವೆ. ನಮಗೆ\nಏನು ಬೇಕು ಏನು ಬೇಡ ಎನ್ನುವುದು ಆ ಭಗವಂತನಿಗೆ ನಮಗಿಂತ ಚೆನ್ನಾಗಿ ಗೊತ್ತು ಮತ್ತು ಆತ ಎಂದೂ\nನಮ್ಮನ್ನು ಬಿಟ್ಟು ಹಾಕುವುದಿಲ್ಲ. ಪೂಜೆ ಕೇವಲ ಭಗವಂತನ ಪ್ರೀತ್ಯರ್ಥವಾಗಿ ಮಾಡಿ ಆತನಲ್ಲಿ ಅನನ್ಯ ಭಕ್ತಿ\nನೆಟ್ಟಾಗ ಭಗವಂತ ನಮ್ಮನ್ನು ಪ್ರೀತಿಸುತ್ತಾನೆ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ. “ತೇಷಾಂ ನಿತ್ಯಾಭಿಯುಕ್ತಾನಾಂ\nಯೋಗಕ್ಷೇಮಂ ವಹಾಮ್ಯಹಮ್‌” -ಇಂತಹ ಭಕ್ತರ ಯೋಗಕ್ಷೇಮದ ಹೊಣೆ ನನ್ನದು ಎಂದು. ಇದಕ್ಕಿಂತ ಹೆಚ್ಚಿನ\nಭರವಸೆ ಏನು ಬೇಕು?\n\nನಾವು ಗಾಢವಾಗಿ “ಭಗವಂತ ನಮ್ಮನ್ನು ರಕ್ಷಿಸಿಯೇ ರಕ್ಷಿಸುತ್ತಾನೆ” ಎಂದು ಗಟ್ಟಿಯಾಗಿ ನಂಬಿದರೆ ಆತ\nರಕ್ಷಿಸಿಯೇ ರಕ್ಷಿಸುತ್ತಾನೆ. ಭಗವಂತನ ಮೇಲಿನ ನಮ್ಮ ನಂಬಿಕೆಯಲ್ಲಿ ನಾವು ಎಂದೂ ವಿಚಲಿತರಾಗಬಾರದು.\n\nಅದು ದೃಢವಾಗಿರಬೇಕು. ಗುರಿ ಕೇವಲ ಭಗವಂತನನ್ನು ಸೇರುವತ್ತ ಇರಬೇಕು. ಭಗವಂತ ಏನು ಕೊಟ್ಟನೋ\nಅದೇ ಮಹಾ ಪ್ರಸಾದವೆಂದು ಸ್ವೀಕರಿಸಿ ಸಂಪೂರ್ಣ ಆತನಲ್ಲಿ ಶರಣಾಗಬೇಕು. ಇಂತಹ ಸ್ಥಿತಿಯಲ್ಲಿ ನಮಗೆ\nಎಂದೂ ದುಃಖವಾಗುವುದಿಲ್ಲ. ಬದುಕು ಆನಂದಮಯವಾಗಿರುತ್ತದೆ. ಜೀವನದಲ್ಲಿ ಏನೇ ಘಟನೆ ನಡೆದರೂ\n“ಭಗವಂತನ ಚಿತ್ತದಂತೆ ಆಯಿತು” ಎಂದು ತಿಳಿದು ಅದನ್ನು ಸಂತೋಷದಿಂದ ಸ್ವೀಕರಿಸುವ ಮನೋವೃತ್ತಿ\nನಮ್ಮದಾಗಬೇಕು. ಇದು ಮೋಕ್ಷದ ಹೆಬ್ಬಾಗಿಲು.\n",
  "9.23": "ಯೇ ಅಪಿ ಅನ್ಯ ದೇವತಾ ಭಕ್ತಾಃ ಯಜಂತೇ ಶ್ರದ್ಧಯಾ ಅನ್ವಿತಾಃ ।\nತೇ ಅಪಿ ಮಾಮ್‌ ಏವ ಕೌಂತೇಯ ಯಜಂತಿ ಅವಿಧಿ ಪೂರ್ವಕಮ್‌ - ಕೌಂತೇಯಾ, ಯಾರು ಬೇರೆ ದೇವತೆಗಳ\nಭಕ್ತರಾಗಿ ಶ್ರದ್ಧೆಯಿಂದ ಅವರನ್ನು ಆರಾಧಿಸುತ್ತಾರೋ ಅಂತವರು ಕೂಡಾ ತಪ್ಪುದಾರಿಯಿಂದ ನನ್ನನ್ನೇ\n\nಆರಾಧಿಸುತ್ತಾರೆ.",
  "9.24": "ಅಹಮ್‌ ಹಿ ಸರ್ವಯಜ್ಞಾನಾಮ್‌ ಭೋಕ್ತಾ ಚ ಪ್ರಭುಃ ಏವ ಚ ।\n\nನ ತು ಮಾಮ್‌ ಅಭಿಜಾನಂತಿ ತತ್ತ್ವೇನ ಅತಃ ಚ್ಯವಂತಿ ತೇ - ನಾನೇ ಅಲ್ಲವೇ ಎಲ್ಲಾ ಪೂಜೆಗಳನ್ನು\nಕೊಳ್ಳುವವನು ಮತ್ತು ನಡೆಸುವವನು. ನಿಜವಾಗಿ ಅವರು ನನ್ನನ್ನು ಚೆನ್ನಾಗಿ ತಿಳಿದಿಲ್ಲ. ಆದ್ದರಿಂದ ಜಾರಿ\nಬೀಳುತ್ತಾರೆ.\n\nಹಿಂದೆ ವಿಶ್ಲೇಶಿಸಿದಂತೆ ಕೆಲವರು ತಮ್ಮ ಬಯಕೆಗಳನ್ನು ಈಡೇರಿಸುವಂತೆ ಕೋರಿ ದೇವತೆಗಳನ್ನು\nಪ್ರಮುಖವಾಗಿ (ಭಗವಂತನಿಗಿಂತ ಬಿನ್ನವಾಗಿ) ಪೂಜಿಸುತ್ತಾರೆ. ಹೀಗೆ ಮಾಡಿದಾಗ ಏನಾಗುತ್ತದೆ ಎನ್ನುವ ಪ್ರಶ್ನೆ\nನಮಗೆ ಮೂಡಬಹುದು. ಹಿಂದೆ ಕೃಷ್ಣ ಹೇಳಿದ್ದ “ಎಲ್ಲವುದರಲ್ಲೂ ಇರುವವನು ನಾನು” ಎಂದು. ಯಾರನ್ನು\nಪ್ರಮುಖವಾಗಿ ಪೂಜಿಸಿದರೂ ಕೂಡಾ ಅದು ಸಲ್ಲುವುದು ಭಗವಂತನನ್ನೇ. ಇಲ್ಲಿ ಸಮಸ್ಯೆ ಎಂದರೆ ಪೂಜೆ\nಮಾಡುವವರಿಗೆ ಆ ಅರಿವು ಇಲ್ಲದಿರುವುದು. ಇದರಿಂದ ತಪ್ಪು ಅನುಸಂಧಾನ. ಅರಿವಿಲ್ಲದೇ ಮಾಡುವ ಭಕ್ತಿ\nಪೂರ್ಣ ಭಕ್ತಿಯಾಗಲಾರದು. ಪರತತ್ವದ ಎಚ್ಚರ ಇಲ್ಲದೇ ಮಾಡುವ ಪೂಜೆ. ಎಂದೂ ನಮ್ಮನ್ನು\nಉನ್ನತಿಗೇರಿಸಲಾರದು. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ಈ ರೀತಿಯ ಪೂಜೆಯಿಂದ ಪುಣ್ಯ ಗಳಿಸುವ ಬದಲು, ಪುಣ್ಯ ಕರ್ಮ\nಮಾಡಿಯೂ ಜಾರಿ ಬಿದ್ದಂತೆ” ಎಂದು. ಆದ್ದರಿಂದ ಯಾವ ಪೂಜೆಯನ್ನೇ ಆಗಲಿ ಪರತತ್ವದ ಎಚ್ಚರದಿಂದ\nಮಾಡಿದಾಗ ಮಾತ್ರ ಅದು ಸಾರ್ಥಕ. ಯಾರನ್ನೇ ಪೂಜಿಸಿದರೂ ಆ ಪೂಜೆ ಅಂತತಃ ಸಲ್ಲುವುದು\n\nಭಗವಂತನನ್ನೇ. ಏಕೆಂದರೆ ಸರ್ವ ಯಜ್ಞಗಳ ಭೋಕ್ತಾರ ಭಗವಂತ. ಇದು ಯಜ್ಞದ ಹಿಂದಿರುವ ಯಜ್ಞಪುರುಷನ\nರಹಸ್ಯ, ಪುರುಷಸೂಕ್ತದಲ್ಲಿ ಹೇಳುವಂತೆ \"ಯಜ್ಞೇನ ಯಜ್ಞ ಮಯಜಂತ ದೇವಾಃ”-ಯಜ್ಞದಿಂದ ಯಜ್ಞ ನಾಮಕ\nಭಗವಂತನ ಆರಾಧನೆ. ಯಜ್ಞಗಳ ಭೋಕ್ತ, ಯಜ್ಞಗಳ ಸ್ವಾಮಿ, ಯಜ್ಞ ಶಬ್ದವಾಚ್ಯನಾದ ಭಗವಂತನ\nಆರಾಧನೆಯಿಂದ ನಾವು ಭಗವಂತನನ್ನು ಸೇರಬಹುದು.\n\nಹೀಗಿದ್ದರೂ ಕೂಡಾ ಸಮಾಜದಲ್ಲಿ ನಾವು ಅನೇಕ ರೀತಿಯಲ್ಲಿ ದೇವತಾ ಆರಾಧನೆ ಮಾಡುವವರನ್ನು\nನೋಡುತ್ತೇವೆ. ಅಂತವರು ಆ ದೇವತೆಯನ್ನು ಪೂಜಿಸುವುದರಲ್ಲೇ ಶ್ರದ್ಧೆ ಇಟ್ಟಿರುತ್ತಾರೆ. ಆ ರೀತಿ ಪೂಜೆ\nಮಾಡುವವರ ಗತಿ ಏನು? ಇದಕ್ಕೆ ಕೃಷ್ಣ ಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ಉತ್ತರಿಸುತ್ತಾನೆ.\n",
  "9.25": "ಯಾಂತಿ ದೇವವ್ರತಾಃ ದೇವಾನ್‌ ಪಿತ್ಯ-ನ್‌ ಯಾಂತಿ ಪಿತೃವ್ರತಾಃ |\n\nಭೂತಾನಿ ಯಾಂತಿ ಭೂತೇಜ್ಯಾಃ ಯಾಂತಿ ಮತ್‌ ಯಾಜಿನಃ ಅಪಿ ಮಾಮ್‌-ದೇವತೆಗಳ ನೇಮ ಹಿಡಿದವರು\nದೇವತೆಗಳನ್ನು ಸೇರುತ್ತಾರೆ. ಪಿತೃಗಳ ನೇಮ ಹಿಡಿದವರು ಪಿತೃಗಳನ್ನು ಸೇರುತ್ತಾರೆ. ದೆವ್ವಗಳನ್ನು\nಪೂಜಿಸುವವರು ದೆವ್ವಗಳನ್ನು ಸೇರುತ್ತಾರೆ. ನನ್ನನ್ನು ಪೂಜಿಸುವವರು ನನ್ನನ್ನೇ ಸೇರುತ್ತಾರೆ.\n\nಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ನೀವು ಯಾರನ್ನು ಪೂಜಿಸುತ್ತೀರೋ ಅವರನ್ನೇ ಪಡೆಯುತ್ತೀರಿ” ಎಂದು. ದೇವತೆಗಳನ್ನು\nಪೂಜಿಸುವವರು ದೇವತೆಗಳನ್ನೂ, ಪಿತೃಗಳನ್ನು ಪೂಜಿಸುವವರು ಪಿತೃಗಳನ್ನೂ, ಭೂತ ಪ್ರೇತವನ್ನು(ದೇವತಾ\nಗಣ) ಪೂಜಿಸುವವರು ಭೂತ ಪ್ರೇತಗಳನ್ನೂ ಪಡೆಯುತ್ತಾರೆ. ಆದರೆ ಯಾರು ಏಕಭಕ್ತಿಯಿಂದ ಎಲ್ಲವುದರಲ್ಲೂ\nಭಗವಂತನನ್ನು ಕಂಡು ಶ್ರದ್ಧೆಯಿಂದ ಆತನನ್ನು ಪೂಜಿಸುತ್ತಾರೋ- “ಅವರು ನನ್ನನ್ನು ಸೇರುತ್ತಾರೆ”- ಎನ್ನುವ\nಭರವಸೆಯನ್ನು ಇಲ್ಲಿ ಕೃಷ್ಣ ಕೊಡುತ್ತಾನೆ. ದೇವತೆಗಳನ್ನು ಪೂಜಿಸಿ ಸ್ವರ್ಗವನ್ನು ಪಡೆಯಬಹುದು, ಆದರೆ ಮರಳಿ\nಹುಟ್ಟದ ಮೋಕ್ಷವನ್ನಲ್ಲ. ಯಾವ ಪೂಜೆ ಮಾಡಿದರೂ ಸರಿಯೇ, ಪ್ರತಿಯೊಂದು ಕ್ರಿಯೆಯ ಹಿಂದೆ ಭಗವಂತನ\nಅರಿವಿದ್ದು ಅದರಿಂದ ಅವನನ್ನು ಆರಾಧಿಸುವುದೇ ನಿಜವಾದ ಪೂಜೆ. ಅರಿವಿಲ್ಲದ ಪೂಜೆ ಎಂದೂ ನಮ್ಮನ್ನು\nಮೋಕ್ಷದತ್ತ ಕೊಂಡೊಯ್ಯುವುದಿಲ್ಲ. ಬ್ರಹ್ಮಾದಿ ಸಮಸ್ತ ದೇವತಾ ಪರಿವಾರ ಸಮೇತನಾಗಿರತಕ್ಕಂತಹ\nಭಗವಂತನ ಆರಾಧನೆ ಮಾಡಿದರೆ ಆಗ ಭಗವಂತನನ್ನು ಸೇರುತ್ತಾರೆ. ಇದು ಶಾಸ್ತ್ರದ ವ್ಯವಸ್ಥೆ.\n\nಮುಂದಿನ ಶ್ಲೋಕಕ್ಕೆ ಹೋಗುವ ಮುನ್ನ ಇಲ್ಲಿ ನಾವು ಒಂದು ವಿಚಾರವನ್ನು ಸ್ಪಷ್ಟವಾಗಿ ತಿಳಿಯಬೇಕು. ನಾವು\nನಮ್ಮ ದೈನಂದಿನ ಜೀವನದಲ್ಲಿ ಗಣಹೋಮ, ನವಗ್ರಹಹೋಮ, ದೈವಾರಾಧನೆ, ಸಂಕಷ್ಟಿ, ಇತ್ಯಾದಿ ರೂಪದಲ್ಲಿ\nಉಪಾಸನೆ ಮಾಡುತ್ತೇವೆ. ಇದು ತಪ್ಪೇ? ನಾವು ಗಣಪತಿ ಅಥವಾ ಇನ್ಯಾವುದೋ ಪ್ರತೀಕದಲ್ಲಿ ಭಗವಂತನ\nಆರಾಧನೆ ಮಾಡಿದರೆ ನಮಗೆ ಮೋಕ್ಷ ಪ್ರಾಪ್ತಿ ಇಲ್ಲವೇ? ಯಾವುದು ಸರಿ, ಯಾವುದು ತಪ್ಪು? ಯಾವುದು\nತ್ರೈವಿಧ್ಯಧರ್ಮ, ಯಾವುದು ಭಾಗವತ ಧರ್ಮ ?\n\nನಮ್ಮಲ್ಲಿ ಇಂದು ಭಾಗವತ ಧರ್ಮ ಕಣ್ಮರೆಯಾಗುತ್ತಿದೆ. ಯಾವುದೇ ಪ್ರತೀಕದ ಅಂತರ್ಯಾಮಿ ಭಗವಂತನ\nಪೂಜೆ ತಪ್ಪಲ್ಲ. ಆದರೆ ಅದರ ಹಿಂದಿರುವ ನಮ್ಮ ಸಂಕಲ್ಪ ತಪ್ಪು. ಉದಾಹರಣೆಗೆ ನವಗ್ರಹ ಹೋಮ. ಒಂದು\nವೇಳೆ ನಾವು ಯಾವ ಫಲ ಕಾಮನೆಯೂ ಇಲ್ಲದೆ, ಕೇವಲ ಮೋಕ್ಷ ಪ್ರಾಪ್ತಿಗಾಗಿ, ಸಕಲ ದೇವತಾಪರಿವಾರನಾದ,\nನವಗ್ರಹ ಅಂತರ್ಗತ ನಾರಾಯಣ ಪ್ರೀತ್ಯರ್ಥ ನವಗ್ರಹ ಹೋಮ ಮಾಡಿದರೆ ಏನೂ ತಪ್ಪಿಲ್ಲ. ಆದರೆ ಅಲ್ಲಿ\nನಾವು \"ನವಗ್ರಹ ಅಂತರ್ಗತ ನಾರಾಯಣ ಪ್ರಸನ್ನನಾಗಿ ಆ ಮೂಲಕ ನವಗ್ರಹ ದೋಷ ಪರಿಹಾರ ಮಾಡಲಿ'\nಎಂದು ಸಂಕಲ್ಪ ಮಾಡಿದಾಗ ಅದು ತ್ರೈವಿಧ್ಯ ಧರ್ಮವಾಗುತ್ತದೆ. ಸಂಕಲ್ಪ ಮಾಡುವಾಗ ಯಾವುದೇ ಕಾಮನೆ\nಸೇರಿಸದೆ ಕೇವಲ ಭಗವದ್‌ ಪ್ರೀತ್ಯರ್ಥ ಎಂದು ಯಾವ ಕಾಮ್ಯ ಕರ್ಮ ಮಾಡಿದರೂ ಅದು ಭಾಗವತ ಧರ್ಮ.\nಭಗವಂತ ಸುಪ್ರೀತನಾದರೆ ಎಲ್ಲವೂ ಸಿದ್ಧಿಸಿದಂತೆ. ಅವನು ಕೊಟ್ಟದ್ದನ್ನು ಸಂತೋಷವಾಗಿ ಭೋಗಿಸು,\nಕೊಡದಿದ್ದುದನ್ನು ಬಯಸಬೇಡ. ನಿನಗೆ ಬಂದ ಕಷ್ಟ ನಿವಾರಣೆ ಮಾಡು ಎಂದು ಭಗವಂತನನ್ನು ಪೂಜಿಸಬೇಡ,\nಬದಲಿಗೆ ಬಂದದ್ದನ್ನು ಪ್ರಸಾದವಾಗಿ ಸ್ವೀಕರಿಸು ಮತ್ತು ಜ್ಞಾನ ವೈರಾಗ್ಯ ಭಕ್ತಿ-ಮೋಕ್ಷ ಕೊಡು ಎಂದು ನಿರಂತರ\nಭಗವಂತನನ್ನು ಪ್ರಾರ್ಥಿಸು. ನಿನ್ನ ರಕ್ಷಣೆಯ ಭಾರ ಆ ಭಗವಂತನದ್ದು. ಅದಕ್ಕಾಗಿ ನೀನು ತಲೆ ಕೆಡಿಸಿಕೊಳ್ಳಬೇಡ.\nನಿನ್ನ ಜೀವನದಲ್ಲಿ ಏನು ನಡೆಯುತ್ತಿದೆ ಅದು ಆಕಸ್ಮಿಕವಲ್ಲ. ಅದು ಭಗವಂತನ ಇಚ್ಛೆ, ಅದರ ನಿವಾರಣೆಗಾಗಿ\nನೀನು ಭಗವಂತನನ್ನು ಪೂಜಿಸುವುದಲ್ಲ ಬದಲಿಗೆ ಭಗವಂತನನ್ನು ಸೇರಲು ಭಗವಂತನನ್ನು ಪೂಜಿಸುವುದು. ಈ\nರೀತಿ ನಾವು ನಮ್ಮ ಸಂಕಲ್ಪದ ಹಿಂದಿನ ಅನುಸಂಧಾನವನ್ನು ಬದಲಿಸಿಕೊಂಡಾಗ ಅದು ಭಾಗವತ\nಧರ್ಮವಾಗುತ್ತದೆ. ಒಬ್ಬ ತ್ರೈವಿಧ್ಯ ತನ್ನ ಗುರುವಿಗೆ “ನನ್ನ ಗುರು' ಎಂದು ನಮಸ್ಕಾರ ಮಾಡಿದರೆ ಭಾಗವತ \"ಆ\nಗುರುಗಳ ಒಳಗೆ ಭಗವಂತ ಕೂತು ನನಗೆ ಪಾಠ ಹೇಳುತ್ತಿದ್ದಾನೆ' ಎಂದು ತಿಳಿದು ನಮಸ್ಕಾರ ಮಾಡುತ್ತಾನೆ.\nಭಾಗವತ ತನ್ನೆಲ್ಲಾ ಕ್ರಿಯೆಯಲ್ಲಿ ಭಗವಂತನನ್ನು ಕಾಣುತ್ತಾನೆ. ಆತ ತನ್ನೆಲ್ಲಾ ಕ್ರಿಯಾ ಕರ್ಮದಲ್ಲಿ ಮೋಕ್ಷ ಮತ್ತು\nಭಗವಂತನನ್ನು ಬಿಟ್ಟು ಇನ್ನೇನನ್ನೂ ಬಯಸುವುದಿಲ್ಲ. ಆತನ ಪೂಜಾ ಸಂಕಲ್ಪದಲ್ಲಿ ಮೋಕ್ಷದ ಬಯಕೆಯನ್ನು\nಬಿಟ್ಟು ಇನ್ಯಾವುದೇ ಬಯಕೆ ಇರುವುದಿಲ್ಲ. ನಾವು ಈ ಎತ್ತರಕ್ಕೇರುವುದು ಅಸಾಧ್ಯವಲ್ಲ. ಇದನ್ನು ಸಾಧ್ಯ\nಮಾಡಲು ಪ್ರಯತ್ನ ಬೇಕು ಅಷ್ಟೆ . ನಾವು ಎಷ್ಟು ಎಷ್ಟು ಭಗವದ್‌ ಪ್ರೀತ್ಯರ್ಥ ಕರ್ಮ ಮಾಡುತ್ತೇವೋ ಅಷ್ಟು ಅಷ್ಟು\nಹೆಚ್ಚು ಮೋಕ್ಷಕ್ಕೆ ಹತ್ತಿರವಾಗುತ್ತೇವೆ. ಭಗವಂತನಲ್ಲಿ “ನನಗೆ ಇದನ್ನು ಕೊಡು' ಎಂದಾಗಾಲೀ ಅಥವಾ “ಇದನ್ನು\nನಿವಾರಿಸು' ಎಂದಾಗಲಿ ಎಂದೂ ಕೇಳಬೇಡ. ನಿನಗೆ ಏನು ಬೇಕು ಎನ್ನುವುದು ಭಗವಂತನಿಗೆ ಗೊತ್ತಿದೆ, ಅದನ್ನು\nಭಗವಂತನಿಗೆ ಬಿಡು. ಕೇವಲ ಭಗವದ್‌ ಪ್ರೀತಿಗಾಗಿ, ಮೋಕ್ಷ ಸಾಧನೆಗಾಗಿ ಕರ್ಮ ಮಾಡು”. “ಇದು ಕೇವಲ\nಭೀಮಸೇನ/ವಾಯುದೇವರಿಗೆ ಮಾತ್ರ” ಎಂದು ಪಲಾಯನ ವಾದ ಮಾಡದೇ, ಯಾವುದೇ ಫಲ ಕಾಮನೆ\nಇಲ್ಲದೇ ಪೂರ್ಣ ಭಕ್ತಿಯಿಂದ ಭಗವಂತನ ಪೂಜೆ ಮಾಡು. ಪೂಜೆಯಲ್ಲಿ ನಿನಗೆ ಬೇಡಲು ಇರುವ ಅಧಿಕಾರ ಕೇವಲ\nಮೋಕ್ಷ ಮತ್ತು ಭಗವಂತ'. ಅದನ್ನು ಪಡೆಯಲು ನಿನ್ನ ಸಾಧನೆಯನ್ನು ಮೀಸಲಿಡು. ಜೀವನದಲ್ಲಿ ಬರುವ ಏಳು\nಬೀಳು ಎಲ್ಲವೂ ನಶ್ವರ, ಆ ಬಗ್ಗೆ ಯೋಚಿಸದೇ, ಸಂಸಾರದಿಂದ ಕಳಚಿಕೊಂಡು ಸಾವಿಲ್ಲದ ಮೋಕ್ಷವನ್ನು\nಸೇರುವುದಕ್ಕಾಗಿ ಸಾಧನೆ ಮಾಡು. ಇದು ಇಲ್ಲಿರುವ ಮೂಲ ಸಂದೇಶ.\n\nಭಗವಂತನ ಪೂಜೆಗೆ ಬೇಕಾಗಿರುವುದು ಧನ-ಕನಕವಲ್ಲ. ಕೇವಲ ನಿಷ್ಕಾಮ ಭಕ್ತಿ. ಭಗವಂತನ ಪೂಜೆ ಎಷ್ಟು\nಸುಲಭ ಎನ್ನುವುದನ್ನು ಕೃಷ್ಣ ಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ವಿವರಿಸುತ್ತಾನೆ:\n",
  "9.26": "ಪತ್ರಮ್‌ ಪುಷ್ಪಮ್‌ ಫಲಮ್‌ ತೋಯಮ್‌ ಯಃ ಮೇ ಭಕ್ಕ್ಯಾ ಪ್ರಯಚ್ಛತಿ ।\n\nತತ್‌ ಅಹಮ್‌ ಭಕ್ತಿ ಉಪಹೃತಮ್‌ ಅಶ್ನಾಮಿ ಪ್ರಯತ ಆತ್ಮನಃ -ಯಾರು ಎಲೆಯನ್ನೋ, ಹೂವನ್ನೋ,\nನೀರನ್ನೋ ಭಕ್ತಿಯಿಂದ ನನಗೆ ನೀಡುತ್ತಾನೋ, ನನ್ನಲ್ಲೇ ಬಗೆಯಿಟ್ಟ ಅವನ ಭಕ್ತಿಯ ಆ ಕೊಡುಗೆಯನ್ನು ನಾನು\nನಲ್ಮೆಯಿಂದ ಕೊಳ್ಳುತ್ತೇನೆ.\n\nಮಹೋನ್ನತನಾದ ಭಗವಂತನ ಪೂಜೆಗೆ ಮೂಲವಾಗಿ ಬೇಕಾಗಿರುವುದು ತನ್ನನ್ನು ತಾನು ಸಂಪೂರ್ಣ\nತೊಡಗಿಸಿಕೊಳ್ಳುವುದು(involvement), ಮತ್ತು \"ಮನಸ್ಸು ತುಂಬಿ ಆರಾಧನೆ' ಮಾಡುವುದು. ಮನಸ್ಸಿನಲ್ಲಿ ಭಕ್ತಿ\nತುಂಬಿ ತುಳಸಿ ಪತ್ರೆಯನ್ನೋ, ಹೂವನ್ನೋ ಅರ್ಪಿಸಿದರೆ ಅದನ್ನು ಭಗವಂತ ಪ್ರೀತಿಯಿಂದ ಸ್ವೀಕರಿಸುತ್ತಾನೆ.\nಇಲ್ಲಿ ಬಂಗಾರದ ಪೀಠವಾಗಲೀ, ಬೆಳ್ಳಿಯ ಹರಿವಾಣವಾಗಲೀ, ಪಂಚಪಾತ್ರೆಯಾಗಲಿ ಏನೂ ಬೇಡ. ಮನೆಯಲ್ಲಿ,\nಮನೆ ತೋಟದಲ್ಲಿ ಏನಿದೆ ಅದನ್ನೇ ಅರ್ಪಿಸು. ಮನೆಯಲ್ಲಿ ಹಾಲಿಲ್ಲದಿದ್ದರೆ ಒಂದು ಲೋಟ ನೀರನ್ನು ಭಕ್ತಿಯಿಂದ\nಅರ್ಪಿಸು. ಆದರೆ ಅದರ ಹಿಂದೆ ಭಾವಶುದ್ಧಿ ಇರಲಿ ಅಷ್ಟೆ , ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ಯೋ ಮೇ ಭಕ್ತ್ಯಾ ಪ್ರಯಚ್ಛತಿ”\nಎಂದು. ಭಗವಂತ ಬಯಸುವುದು ನಮ್ಮ ಅಂತರಂಗದ ಪ್ರೀತಿಯನ್ನು ಮತ್ತು ಹೃದಯವಂತಿಕೆಯನ್ನು ಹೊರತು\nಹೊರಗಿನ ವೈಭವವನ್ನಲ್ಲ. “ತದಹಂ ಭಕ್ಕುಪಹೃತಮಶ್ನಾಮಿ ಪ್ರಯತಾತ್ಮನಃ”-“ನೀನು ಮನಸ್ಸನ್ನು ನನ್ನಲ್ಲಿ\nನೆಲೆಗೊಳಿಸಿ, ಭಕ್ತಿಯಿಂದ ಏನು ಕೊಟ್ಟರೂ ಅದನ್ನು ನಾನು ಸ್ವೀಕರಿಸುತ್ತೇನೆ” ಎನ್ನುತ್ತಾನೆ. ಕೃಷ್ಣ.\nರಾಮಾಯಣದಲ್ಲಿ ಬರುವ ಶಬರಿಯ ಕಥೆ ಭಗವಂತನ ಈ ನುಡಿಗೆ ಒಂದು ದೃಷ್ಟಾಂತ.\n",
  "9.27": "ಯತ್‌ ಕರೋಷಿ ಯತ್‌ ಅಶ್ನಾಸಿ ಯತ್‌ ಜುಹೋಷಿ ದದಾಸಿ ಯತ್‌ |\nಯತ್‌ ತಪಸ್ಯಸಿ ಕೌಂತೇಯ ತತ್‌ ಕುರುಷ್ಟ ಮತ್‌ ಅರ್ಪಣಮ್‌ -- ಕೌಂತೇಯಾ, ಏನು ಮಾಡುವೆ, ಏನು\nತಿನ್ನುವೆ, ಏನು ಹೋಮಿಸುವೆ, ಏನು ನೀಡುವೆ, ಏನು ತಪಗೈವೆ ಅದನ್ನು ನನಗೆ ಒಪ್ಪಿಸು.\n\nಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ. “ನನಗಾಗಿ ನೀನು ಏನನ್ನೂ ಮಾಡುವುದು ಬೇಡ ಆದರೆ ನಿನಗೋಸ್ಕರ ಏನು\nಮಾಡುತ್ತೀಯೋ ಅದನ್ನು ನನಗೆ ಅರ್ಪಿಸು” ಎಂದು. ನಮ್ಮ ನಿತ್ಯ ಜೀವನದಲ್ಲಿ ಮಾಡಬೇಕಾದ ಅನೇಕ\nಅನಿವಾರ್ಯ ವೃತ್ತಿ ಕಾರ್ಯಗಳಿರುತ್ತವೆ. ಜೀವನ ನಿರ್ವಹಣೆಯ ಕಾಯಕವಿರುತ್ತದೆ. ನಾವು ಅದನ್ನೇ ಭಗವಂತನ\nಪೂಜೆ ಎಂದು ತಿಳಿದು ಮಾಡಬೇಕು. ಇದಕ್ಕೆ ಉತ್ತಮ ದೃಷ್ಟಾಂತ ಧರ್ಮವ್ಯಾಧನ ಕಥೆ. ಮಾಂಸ ವಿಕ್ರಯ ಮಾಡಿ\nಜೀವನ ಸಾಗಿಸುತ್ತಿದ್ದ ಆತನಲ್ಲಿ ಒಂದು ಸಂಕಲ್ಪ ಇತ್ತು. “ಮಾಂಸ ಮಾರುವುದು ನನಗೆ ಆನುವಂಶೀಯವಾಗಿ\n\nಬಂದ ಅಭ್ಯಾಸ. ಆದ್ದರಿಂದ ನಾನು ಮಾಂಸ ಮಾರುತ್ತೇನೆ, ನನಗೆ ಬದುಕುವುದಕ್ಕೋಸ್ಕರ ಮತ್ತು ನನ್ನ\nತಂದೆತಾಯಿಯನ್ನು ಸಾಕುವುದಕ್ಕೋಸ್ಕರ ನನ್ನ ಪಾಲಿಗೆ ಬಂದ ಈ ವೃತ್ತಿಯನ್ನು ನಾನು ಮಾಡುತ್ತೇನೆ.\nಇದರಿಂದ ನನ್ನ ಬದುಕಿಗೆ ಬೇಕಾದಷ್ಟನ್ನು ಮಾತ್ರ ನಾನು ಗಳಿಸುತ್ತೇನೆ. ಎಂದೂ ವ್ಯವಹಾರದಲ್ಲಿ ಜನರ\nಶೋಷಣೆ ಮಾಡುವುದಿಲ್ಲ” ಎಂದುಕೊಂಡು ಮಾಂಸ ವಿಕ್ರಯ ಮಾಡುತ್ತಿದ್ದ ಆತ. ಇದರಿಂದ ಆತನಿಗೆ ದೊಡ್ಡ\nಜ್ಞಾನಿ ಧರ್ಮವ್ಯಾಧ ಎನ್ನುವ ಹೆಸರು ಬಂತು. ಋಷಿ ಮುನಿಗಳು ಆತನಿಂದ ಪಾಠ ಕಲಿಯುವ ಪ್ರಸಂಗ ಬಂತು.\nಇದಕ್ಕೆ ಮೂಲ ಕಾರಣ ಆತ ತಾನು ಏನು ಮಾಡುತ್ತಿದ್ದನೋ ಅದನ್ನು ದೇವರ ಪೂಜೆ ಎಂದು ಮಾಡಿದ್ದು ಅಷ್ಟೇ.\nಹೀಗೆ ನಾವು ಮಾಡುವ ವೃತ್ತಿ ಮುಖ್ಯವಾಗುವುದಿಲ್ಲ, ಬದಲಿಗೆ ಅದನ್ನು ಭಗವಂತನ ಪೂಜೆ ಎಂದು ಮಾಡುವ\nಅನುಸಂಧಾನ ಮುಖ್ಯವಾಗುತ್ತದೆ.\nನಿನ್ನ ನಿತ್ಯ ಕರ್ತವ್ಯ ಏನಿದೆ ಅದನ್ನು ಭಗವಂತನಿಗೆ ಅರ್ಪಿಸು. ಅದನ್ನು ಭಗವಂತನ ಪೂಜೆ ಎಂದು ಮಾಡು.\nಭಗವಂತನಿಗಾಗಿ ಭಕ್ಷ್ಯ ಭೋಜ್ಯವನ್ನು ಮಾಡುವ ಅಗತ್ಯವಿಲ್ಲ. ನೀನು ಏನನ್ನು ತಿನ್ನುತ್ತೀಯೋ ಅದನ್ನು\nಭಗವಂತನಿಗೆ ಅರ್ಪಿಸು. ಹೀಗೆ ಮಾಡಿದಾಗ ಭಗವಂತನ ಆರಾಧನೆ ಪ್ರತ್ಯೇಕವಾಗುವುದಿಲ್ಲ ಮತ್ತು\nಕಷ್ಟವಾಗುವುದಿಲ್ಲ. ಭಗವಂತನಿಗಾಗಿ ಯಾವುದೋ ವಿಶೇಷ ಹೋಮ ಹವನ ಮಾಡುವ ಅಗತ್ಯವಿಲ್ಲ. ನೀನು\nಏನು ಹೋಮ ಮಾಡುತ್ತೀಯೋ ಅದನ್ನೇ “ಅಗ್ನಿ ಅಂತರ್ಗತ ನಾರಾಯಣಾಯ ಇದಮ್‌ ನ ಮಮಃ' ಎಂದು\nಅರ್ಪಿಸು. ಒಬ್ಬ ಹಸಿದ ವ್ಯಕ್ತಿಯನ್ನು ಕಂಡರೆ ಆತ ತನ್ನ ಹೊಟ್ಟೆಯಲ್ಲಿ ವೈಶ್ವಾನರ ರೂಪಿ ಭಗವಂತನನ್ನು ಹೊತ್ತು\nಬಂದಿದ್ದಾನೆ ಎಂದು ತಿಳಿದು ಆತನೊಳಗಿರುವ ವೈಶ್ವಾನರ ಪ್ರಸನ್ನನಾಗಲಿ ಎಂದು ಆ ವ್ಯಕ್ತಿಯನ್ನು ಸತ್ಕಾರ\nಮಾಡು. ಇದೇ ಭಗವಂತನ ಮಹಾ ಪೂಜೆ ಎನಿಸುತ್ತದೆ.\nಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ಯತ್ತಪಸ್ಯಸಿ ಕೌಂತೇಯ ತತ್‌ ಕುರುಷ್ಟ ಮದರ್ಪಣಮ್‌” ಎಂದು. ಇಲ್ಲಿ ತಪಸ್ಸು ಎಂದರೆ\n“ಚಿಂತನೆ' ಅಥವಾ ವೃತಾನುಷ್ಟಾನ. ಉದಾಹರಣೆಗೆ \"ಸಂಕಷ್ಟಿ'- ಅದನ್ನು ಆಚರಿಸುವಾಗ ಗಣಪತಿ\nಅಂತರ್ಗತನಾದ ಭಗವಂತನಿಗೆ ಅರ್ಪಿತವಾಗಲಿ ಎಂದು ಮಾಡು. ಅಲ್ಲಿ ಯಾವುದೇ ಫಲಾಪೇಕ್ಷೆ ಅಹಂಕಾರ\nಇಟ್ಟುಕೊಳ್ಳಬೇಡ. ಹೀಗೆ ಯಾವ ಆಚರಣೆಯೂ ಕೂಡಾ ಅಂತತಃ ಪರಮ ಪುರುಷನಾದ ಭಗವಂತನಿಗೆ ಅರ್ಪಿತ\nಎಂದು ತಿಳಿದು ಮಾಡಿದಾಗ ಅದು ನಿಜವಾದ ತಪಸ್ಸಾಗುತ್ತದೆ. ಇಲ್ಲಿ ಅರ್ಜುನನಿಗೆ “ನಿನ್ನ ಕರ್ತವ್ಯ ಕರ್ಮವಾಗಿ\nಬಂದಿರುವ ಈ ಯುದ್ಧವನ್ನೂ ಕೂಡಾ ಭಗವಂತನ ಪೂಜೆಯಾಗಿ ಮಾಡು” ಎನ್ನುವ ಸಂದೇಶವನ್ನು ಈ ಶ್ಲೋಕದ\nಮೂಲಕ ಕೃಷ್ಣ ನೀಡಿದ್ದಾನೆ. ಭಾಗವತ ಧರ್ಮ ಅನುಷ್ಠಾನದಿಂದ ಎನು ಫಲ ಎನ್ನುವುದನ್ನು ಕೃಷ್ಣ ಮುಂದಿನ\nಶ್ಲೋಕದಲ್ಲಿ ವಿವರಿಸುತ್ತಾನೆ.\n",
  "9.28": "ಶುಭ ಅಶುಭ ಭಲೈಃ ಏವಮ್‌ ಮೋಕ್ಷ್ಯಸೇ ಕರ್ಮ ಬಂಧನ್ಯೆಃ |\n\nಸಂನ್ಯಾಸ ಯೋಗ ಯುಕ್ತ ಆತ್ಮಾ ವಿಮುಕ್ತಃ ಮಾಮ್‌ ಉಪೈಷ್ಯಸಿ-ಹೀಗೆ ಬದುಕಿದಾಗ, ಒಳಿತು-ಕೆಡುಕುಗಳ\nಕಡೆಗೆಳೆವ ಕರ್ಮದ ಸೆರೆಯಿಂದ ಪಾರಾಗುವೆ. ಫಲದ ಹಂಗು ತೊರೆದು ಕರ್ತವ್ಯದಲ್ಲಿ ಬಗೆ ತೊಡಗಿಸುತ್ತಾ ಸೆರೆ\nಕಳಚಿಕೊಂಡು ನನ್ನ ಬಳಿ ಸೇರುವೆ.\n\nನಾವು ಯಾವುದೇ ಕರ್ಮವನ್ನು “ನನಗೆ ಇಂತಹ ಫಲ ಬರಬೇಕು' ಎನ್ನುವ ಫಲದ ನಂಟಿನಿಂದ ಮತ್ತು “ನಾನು\nಈ ಕರ್ಮವನ್ನು ಮಾಡಿದೆ' ಎನ್ನುವ ಅಹಮ್‌ ಇದ್ದು ಮಾಡಿದಾಗ ಆ ಕರ್ಮ ನಮಗೆ ಅಂಟುತ್ತದೆ. ಅದಕ್ಕೋಸ್ಕರ\nಹಿಂದಿನ ಕಾಲದಲ್ಲಿ 'ಕರ್ಮಕರಿಷ್ಯೇ' ಎಂದು ಸಂಕಲ್ಪ ಮಾಡುವಾಗ ಈ ರೀತಿ ಹೇಳುತ್ತಿದ್ದರು:\nಭಗವತೋ ಬಲೇನ ಭಗವತೋ ವೀರ್ಯೇನ ಭಗವದಃ ತೇಜಸಾ |\nಭಗವತಾ ಕರ್ಮಣಾ ಕರ್ಮಕರಿಷ್ಯಾಮಿ ಭಗವತೋ ವಾಸುದೇವಸ್ಯಃ ॥|\n\n“ನಾನು ಮಾಡುವ ಕರ್ಮ ನನ್ನ ಕರ್ಮವಲ್ಲ, ನನ್ನೊಳಗಿರುವ ಭಗವಂತ ಮಾಡುವ ಕರ್ಮ. ಅದರ ಹಿಂದಿರುವ\nಶಕ್ತಿ ಸಾಮರ್ಥ್ಯ ಎಲ್ಲವೂ ಭಗವಂತನದ್ದು, ನನ್ನದೇನೂ ಇಲ್ಲ”. ಇದು ಭಾಗವತಧರ್ಮದ ಸಂಕಲ್ಪ. ಭಗವದ್‌\nಪ್ರೀತ್ಯರ್ಥ ಮಾಡಿದ ಯಾವ ಕರ್ಮವೂ ನಮಗೆ ಬಂಧನವಾಗುವುದಿಲ್ಲ. ಬ್ರಹ್ಮಸೂತ್ರದಲ್ಲಿ ವೇದವ್ಯಾಸರು ಇದನ್ನು\nಹೀಗೆ ಹೇಳಿದ್ದಾರೆ: “ಭಗವಂತನ ಜ್ಞಾನ ನಮ್ಮೊಳಗೆ ದೃಢವಾಗಿ ಅಪರೋಕ್ಷವಾದಾಗ, ಹಿಂದೆ ಫಲಕಾಮನೆಯಿಂದ\nಮಾಡಿದ ಎಲ್ಲಾ ಪಾಪಗಳನ್ನು ಆ ಜ್ಞಾನಾಗ್ನಿ ಸುಟ್ಟುಬಿಡುತ್ತದೆ” ಎಂದು. ಆದ್ದರಿಂದ ಜ್ಞಾನ ಎಲ್ಲಕ್ಕಿಂತ ಶ್ರೇಷ್ಠ.\nಇದನ್ನು ನಾವು ಕಠೋಪನಿಷತ್ತಿನಲ್ಲಿ ಬರುವ ಯಮ ಮತ್ತು ನಚಿಕೇತನ ಸಂಭಾಷಣೆಯಲ್ಲಿ ಕಾಣುತ್ತೇವೆ. ಅಲ್ಲಿ\nನಚಿಕೇತ ಯಮನಲ್ಲಿ ಜ್ಞಾನವನ್ನು ವರವಾಗಿ ಬೇಡಿದಾಗ ಯಮ ಆತನಿಗೆ “ನಿನಗೆ ಎಷ್ಟು ಸಂಪತ್ತು ಬೇಕು ಅದನ್ನು\nಕೇಳು, ನಿನ್ನನ್ನು ಬೇಕಿದ್ದರೆ ದೊಡ್ಡ ಸಾಮ್ರಾಜ್ಯದ ಚಕ್ರವರ್ತಿಯನ್ನಾಗಿ ಮಾಡುತ್ತೇನೆ” ಎನ್ನುತ್ತಾನೆ. ಇದಕ್ಕೆ\nನಚಿಕೇತ ಹೇಳುತ್ತಾನೆ “ ಇದೆಲ್ಲವೂ ನರಕಕ್ಕೆ ಹೋಗುವ ಸಾಧನಗಳು, ಇದ್ಯಾವುದೂ ನನಗೆ ಬೇಡ. ನನಗೆ\nಭಗವಂತನ ಬಗ್ಗೆ ತಿಳಿಯಬೇಕು” ಎಂದು. ಹೀಗೆ ನಮ್ಮ ಪಾಪ ಕರ್ಮವನ್ನು ಸಂಪೂರ್ಣ ತೊಳೆದುಕೊಂಡು\nಮೋಕ್ಷಕ್ಕೆ ಹೋಗುವ ಏಕಮಾತ್ರ ಮಾರ್ಗ ಭಗವಂತನ ಬಗೆಗಿನ ಜ್ಞಾನ. ಭಗವದರ್ಪಣ ಬುದ್ಧಿಯಿಂದ ಕರ್ಮ\nಅನುಷ್ಠಾನ ಮಾಡಿದಾಗ ಶುಭಾಶುಭ ಕರ್ಮದ ಶಕಟ್ಟಿನಿಂದ ಬಿಡುಗಡೆ ಸಾಧ್ಯ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ\n“ಸಂನ್ಯಾಸಯೋಗಯುಕ್ತಾತ್ಮಾ ವಿಮುಕ್ತೋ ಮಾಮುಪೈಷ್ಯಸಿ” ಎಂದು. ಇಲ್ಲಿ ಹೇಳುವ ಸಂನ್ಯಾಸ ಒಂದು\nಯೋಗ(ಉಪಾಯ). ಎಲ್ಲವನ್ನೂ ಭಗವಂತನಿಗೆ ಅರ್ಪಣೆ ಮಾಡಿ ಫಲಕಾಮನೆ ಇಲ್ಲದೆ ಭಗವದ್‌ ಪೂಜಾ\nದೃಷ್ಟಿಯಿಂದ ಮಾಡುವಂತಹ ಸಾತ್ವಿಕರ ಸಾಧನೆ. ಸಂನ್ಯಾಸ ಎಂದರೆ ಕಾಮ-ಸಂಕಲ್ಪವನ್ನು ಭಗವಂತನಲ್ಲಿ\nಅರ್ಪಿಸುವುದು. ಕಾಮ ಅಂದರೆ “ಮಾಡಬೇಕು' ಎಂದು ಬಯಸುವುದು, ಸಂಕಲ್ಪ ಎಂದರೆ \"ಮಾಡುತ್ತೇನೆ' ಎಂದು\nನಿರ್ಧರಿಸುವುದು. ಕಾಮಸಂಕಲ್ಪ ವರ್ಜಿತ-ಸಂನ್ಯಾಸ. ಹೀಗೆ ಭಾಗವತ ಧರ್ಮ ಪಾಲನೆ ಮಾಡಿದರೆ ಸುಲಭವಾಗಿ\nಭಗವಂತನನ್ನು ಸೇರಬಹುದು-“ನಿಶ್ಚಿತವಾಗಿಯೂ ನನ್ನನ್ನು ಸೇರುತ್ತಾರೆ” ಎನ್ನುವುದು ಕೃಷ್ಣನ ಭರವಸೆ.",
  "9.29": "ಸಮಃ ಅಹಮ್‌ ಸರ್ವಭೂತೇಷು ನಮೇ ದ್ವೇಷ್ಯಃ ಅಸ್ತಿ ನಪ್ರಿಯಃ ।\n\nಯೇ ಭಜಂತಿ ತು ಮಾಮ್‌ ಭಕ್ತ್ಯಾ ಮಯಿ ತೇ ತೇಷು ಚ ಅಪಿ ಅಹಮ್‌-ಎಲ್ಲಾ ಜೀವಿಗಳೂ ನನಗೆ ಒಂದೆ. ನನಗೆ\nಹಗೆಯನೂ ಇಲ್ಲ, ಗೆಳೆಯನೂ ಇಲ್ಲ. ಆದರೆ ಯಾರು ನನ್ನನ್ನು ಭಕ್ತಿಯಿಂದ ಒಲಿಸುತ್ತಾರೋ ಅವರು ನನ್ನ ವಶ;\nನಾನು ಅವರ ವಶ.\n\nಭಗವಂತನಿಗೆ ಯಾರ ಮೇಲೂ ಹಗೆಯಾಗಲೀ ಅಥವಾ ಗೆಳೆತನವಾಗಲೀ ಇಲ್ಲ. ಆತ ಪ್ರೀತಿಸುವುದು\nವ್ಯಕ್ತಿಯನ್ನಲ್ಲ ಬದಲಿಗೆ ವ್ಯಕ್ತಿಯಲ್ಲಿರುವ ಜ್ಞಾನವನ್ನು ಮತ್ತು ಭಕ್ತಿಯನ್ನು. ಅರ್ಹತೆ ಇದ್ದವರು ಭಗವಂತನನ್ನು\nಭಕ್ತಿಯಿಂದ ಒಲಿಸುತ್ತಾರೆ. ನಿಜವಾದ ಭಕ್ತರಿಗೆ ಭಗವಂತ ವಶನಾಗುತ್ತಾನೆ.\n",
  "9.30": "ಅಪಿ ಚೇತ್‌ ಸು ದುರಾಚಾರಃ ಭಜತೇ ಮಾಮ್‌ ಅನನ್ಯ ಭಾಕ್‌ |\n\nಸಾಧುಃ ಏವ ಸಃ ಮಂತವ್ಯಃ ಸಮ್ಯಕ್‌ ವ್ಯವಸಿತಃ ಹಿ ಸಃ -ಬೇರೆಡೆಗೆ ಬಗೆಗೊಡದೆ ನನ್ನಲ್ಲೇ ಭಕ್ತಿಯಿಡುವವನು\nಎಂತಹ ನಡತೆಗೇಡಿಯಾದರೂ ಮೂಲತಃ ಒಳ್ಳೆಯವನೆಂದೇ ತಿಳಿಯಬೇಕು. ಏಕೆಂದರೆ ಅವನು ಖಚಿತವಾಗಿ\nನಿಜವನರಿತವನು.\n\nನಿಜವಾದ ಭಕ್ತರು ಸಾಮಾನ್ಯವಾಗಿ ಎಂದೂ ದುರಾಚಾರಿಗಳಾಗಿರುವುದಿಲ್ಲ. ಅಕಸ್ಮಾತ್‌ ಒಬ್ಬ ಸಾತ್ವಿಕ\nಯಾವುದೋ ಪ್ರಾರಾಬ್ಧ ಕರ್ಮದಿಂದ ಒಂದು ಜನ್ಮದಲ್ಲಿ ನಡತೆಗೇಡಿಯಾಗಿದ್ದರೂ ಸಹ ಆತ ಮೂಲತಃ\nಉತ್ತಮನೇ ಆಗಿರುತ್ತಾನೆ. ಏಕೆಂದರೆ ಆತ ತನ್ನ ಅನೇಕ ಜನ್ಮದಲ್ಲಿ ಭಗವದ್‌ ಸಾಧನೆ ಮಾಡಿರುತ್ತಾನೆ. ಇದು\nಸಾಮಾನ್ಯರಾದ ನಮಗೆ ಕಾಣದಿದ್ದರೂ ಕೂಡಾ ಭಗವಂತನಿಗೆ ಕಾಣುತ್ತದೆ. ಭಗವಂತನ ದೃಷ್ಟಿಯಲ್ಲಿ ಆತ\nಉತ್ತಮನೆನಿಸಿರುತ್ತಾನೆ. ಈ ಕಾರಣಕ್ಕಾಗಿ ನಾವು ಯಾರನ್ನೂ ಹಗುರವಾಗಿ ಕಾಣಬಾರದು. ಒಬ್ಬ ಕೆಟ್ಟ\nದಾರಿಯಲ್ಲಿ ನಡೆಯುತ್ತಿದ್ದರೆ ಅದಕ್ಕೆ ಅನೇಕ ಕಾರಣಗಳಿರಬಹುದು. ಆತ ಸಾತ್ವಿಕನೂ ಇರಬಹುದು. ಆದರೆ ಆತನ\nಪ್ರರಾಬ್ಧ ಕರ್ಮ ಆತನನ್ನು ಆ ಮಾರ್ಗದಲ್ಲಿ ನಡೆಯುವಂತೆ ಮಾಡಿರಬಹುದು. ಉತ್ತಮನೆನಿಸಿದವನು\nಶಾಶ್ವತವಾಗಿ ಆ ದಾರಿಯಲ್ಲಿ ಸಾಗುವುದಿಲ್ಲ ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ ಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ.",
  "9.31": "ಕ್ಷಿಪ್ರಮ್‌ ಭವತಿ ಧರ್ಮ ಆತ್ಮಾ ಶಶ್ವತ್‌ ಶಾಂತಿಮ್‌ ನಿಗಚ್ಛತಿ ।\nಕೌಂತೇಯ ಪ್ರತಿಜಾನೀಹಿ ನ ಮೇ ಭಕ್ತಃ ಪ್ರಣಶ್ಯತಿ -ಅವನು ಒಡನೆಯೇ ಸರಿದಾರಿ ಹಿಡಿಯುತ್ತಾನೆ; ಅಳಿವಿರದ\nಸುಖದ ಸೆಲೆಯನ್ನು ಪಡೆಯುತ್ತಾನೆ. ಕೌಂತೇಯಾ, ಇದನ್ನು ಆಣೆಯಿಟ್ಟಾಡು: \"ನನ್ನ ಭಕ್ತನೆಂದೂ ಕೆಡುವುದಿಲ್ಲ'.\n\nಹೀಗೆ ಪ್ರರಾಬ್ಧ ಕರ್ಮದಿಂದ ದಾರಿತಪ್ಪಿದವರು ಯಾವುದೋ ಒಂದು ಸಂದರ್ಭದಲ್ಲಿ ಒಡನೆಯೇ ತಾವು\nಮಾಡುತ್ತಿರುವ ತಪ್ಪಿನ ಅರಿವಾಗಿ ಸರಿದಾರಿಯನ್ನು ಹಿಡಿಯುತ್ತಾರೆ, ಮತ್ತು ಅಳಿವಿರದ ಮೋಕ್ಷವನ್ನು ಸೇರುತ್ತಾರೆ.\nಇದು ನಿಶ್ಚಿತ. ಇದನ್ನು ನೀನು ಆಣೆಮಾಡಿ ಹೇಳು ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಇದಕ್ಕೆ ಉತ್ತಮ ಉದಾಹರಣೆ ಅಜಾಮಿಳನ\nಕಥೆ. ತನ್ನ ಜೀವನದಲ್ಲಿ ಮಾಡಬಾರಡದ್ದನ್ನೆ ಲ್ಡಾ ಮಾಡಿದ ಅಜಾಮಿಳ ಮೂಲತಃ ಒಬ್ಬ ಶ್ರೇಷ್ಠ ಜೀವ. ಇಂತಹ\n\nಅಜಾಮಿಳನಿಗೆ ಭಗವಂತ ಜೀವನದ ಕೊನೆಗಾಲದಲ್ಲಿ ಸತ್ಯದ ದಾರಿ ತೋರಿಸಿ ಉದ್ಧಾರ ಮಾಡುತ್ತಾನೆ. ಆತ\nತನ್ನ ಕೊನೆಗಾಲದಲ್ಲಿ ಸಾಧನೆ ಮಾಡಿ ಮೋಕ್ಷವನ್ನು ಸೇರುತ್ತಾನೆ.\nಇಲ್ಲಿ ಕೃಷ್ಣ ಅರ್ಜುನನಲ್ಲಿ ಏಕೆ “ನೀನು ಪ್ರತಿಜ್ಞೆ ಮಾಡು” ಎಂದು ಹೇಳುತ್ತಾನೆ ಎಂದರೆ-ಭಗವಂತ ಭಕ್ತರಿಗಾಗಿ ತನ್ನ\nಪ್ರತಿಜ್ಞೆಯನ್ನು ಮುರಿದಾನು ಆದರೆ ಎಂದೂ ಭಕ್ತರ ಪ್ರತಿಜ್ಞೆಯನ್ನಲ್ಲ. ಇದಕ್ಕೆ ಉದಾಹರಣೆ ಮಹಾಭಾರತ\nಯುದ್ಧದಲ್ಲಿ ನಡೆದ ಒಂದು ಘಟನೆ:\nಮಹಾಭಾರತ ಯುದ್ಧದ ಮೊದಲು ತಾನು ಶಸ್ತ್ರ ಹಿಡಿಯುವುದಿಲ್ಲ ಎಂದು ಪ್ರತಿಜ್ಞೆ ಮಾಡಿದ್ದ ಕೃಷ್ಣ, ಯುದ್ಧದ\nನಡುವೆ ಅರ್ಜುನ ಭೀಷ್ಮನ ಎದುರು ಯುದ್ಧ ಮಾಡುವುದಕ್ಕೆ ಹಿಂಜರಿದಾಗ, ಕೋಪಾವೇಶದಿಂದ ಭೀಷ್ಮನನ್ನು\nಸಾಯಿಸಲೆಂಬಂತೆ ರಥದಚಕ್ರವೊಂದನ್ನು ಹಿಡಿದು ಮುಂದೊತ್ತಿ ಬರುತ್ತಾನೆ! ಇದನ್ನು ನೋಡಿದ ಬೀಷ್ಮ ತನ್ನ\nಎರಡೂ ಕೈಗಳನ್ನು ಜೋಡಿಸಿ ಹೀಗೆ ಹೇಳುತ್ತಾನೆ: \" ಓ ಭಗವಂತಾ; ನಿನ್ನ ಕೈಯಲ್ಲಿ ಚಕ್ರ ಹಿಡಿಸುತ್ತೇನೆ, ಹಾಗೆ\nಯುದ್ಧ ಮಾಡಿಸುತ್ತೇನೆ ಎಂದು ನಾನು ಪ್ರತಿಜ್ಞೆ ಮಾಡಿದ್ದೆ. ಚಕ್ರ ಹಿಡಿಯುವುದಿಲ್ಲ ಎಂದಿದ್ದೆ ನೀನು. ಆದರೆ ಈಗ\nನನ್ನ ಪ್ರತಿಜ್ಞೆಯನ್ನು ಈಡೇರಿಸಲು ನೀನು ಚಕ್ರ ಹಿಡಿದಿರುವೆ. ನಿನ್ನನ್ನೇ ನೀನು ಮರೆತಿರುವೆ, ಆದರೆ ನಿನ್ನ ಭಕ್ತನ\nಪ್ರತಿಜ್ಞೆಯನ್ನಲ್ಲ; ನೀನಲ್ಲದೆ ನಮಗೆ ಗತಿ ಇನ್ಯಾರು?” ಎಂದು. ಈ ಘಟನೆಯಲ್ಲಿ ಭಗವಂತ ಎಂತಹ ಭಕ್ತವತ್ಸಲ\nಎನ್ನುವುದು ತಿಳಿಯುತ್ತದೆ.\n",
  "9.32": "ಮಾಮ್‌ ಹಿ ಪಾರ್ಥ ವ್ಯಪಾ ಶ್ರಿತ್ಯ ಯೇ ಅಪಿ ಸ್ಯುಃ ಪಾಪಯೋನಯಃ |\nಸ್ತ್ರಿಯಃ ವೈಶ್ಯಾಃ ತಥಾ ಶೂದ್ರಾಃ ತೇ ಅಪಿ ಯಾಂತಿ ಪರಾಮ್‌ ಗತಿಮ್‌ -ಪಾರ್ಥಾ, ನನಗೆ ಶರಣು ಬಂದವರು\nಯಾವುದೋ ಪಾಪದಿಂದ ಹೆಣ್ಣಾಗಿ, ವೈಶ್ಯರಾಗಿ, ಶೂದ್ರರಾಗಿ ಸಾಧನೆಯಿಂದ ವಂಚಿತರಾದರೂ ಹಿರಿಯ\n\nನೆಲೆಯಾದ ನನ್ನನ್ನೇ ಪಡೆಯುತ್ತಾರೆ.\n\nಈ ಶ್ಲೋಕ ಕೆಲವು ಭಾಷ್ಯಕಾರರಿಗೇ ಗೊಂದಲ ಮಾಡಿದ ಶ್ಲೋಕ. ಮಧ್ವಾಚಾರ್ಯರು ಈ ಶ್ಲೋಕಕ್ಕೆ ಭಾಷ್ಯ\nನೀಡುವ ತನಕ ಹೆಚ್ಚಿನವರು ಇದಕ್ಕೆ ತಪ್ಪು ಅರ್ಥವನ್ನು ಕಲ್ಪಿಸಿಕೊಂಡಿದ್ದರು. ಮೇಲ್ನೋಟದಲ್ಲಿ ಈ ಶ್ಲೋಕವನ್ನು\nನೋಡಿದಾಗ “ಸ್ತ್ರೀಯರು, ವೈಶ್ಯರು ಮತ್ತು ಶೂದ್ರರು ಪಾಪಿಗಳು” ಎಂದು ತಿಳಿಯುವ ಅಪಾಯ ಹೆಚ್ಚು. ಇಲ್ಲಿ ಕೃಷ್ಣ\nಹೇಳುತ್ತಿರುವುದು ಸ್ತ್ರೀ ಜೀವದ ಬಗ್ಗೆ ಅಲ್ಲ. ಸ್ತ್ರೀಯರು ಪಾಪಿಗಳಲ್ಲ. ಯಾವುದೋ ಪಾಪದಿಂದ ಅಥವಾ\nಶಾಪದಿಂದ ಸ್ತ್ರೀ ಜನ್ಮ ಪಡೆದ ಗಂಡು “ಸ್ತ್ರೀ ಪಾಪಯೋನಿ' ಹೊರತು ಹೆಣ್ಣಾಗಿರುವ ಸ್ತ್ರೀಜೀವ ಪಾಪಯೋನಿಯಲ್ಲ.\nಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ಯಾವುದೋ ಪಾಪದಿಂದ ಹೀನಯೋನಿ ಬಂದಿರಬಹುದು, ಆದರೆ ಅಂತವರು ನನ್ನನ್ನು\nಆರಾಧಿಸಿ ಎಲ್ಲಾ ದೋಷಗಳಿಂದ ಬಿಡುಗಡೆ ಹೊಂದಬಹುದು” ಎಂದು. ಇದಕ್ಕೆ ಉತ್ತಮ ದೃಷ್ಟಾಂತ\nನರಕಾಸುರನ ಸೆರೆಯಲ್ಲಿದ್ದ ಹದಿನಾರು ಸಾವಿರದ ನೂರು ಮಂದಿ ಸ್ತ್ರೀಯರು. ಇವರು ಅಗ್ನಿ ಪುತ್ರರು.\nಭಗವಂತನ ಪತ್ನಿಯರಾಗಬೇಕು ಎಂಬ ಆಸೆಯಿಂದ ತಮ್ಮ ಎತ್ತರವನ್ನು ಕಳೆದುಕೊಂಡು ಭೂಮಿಯಲ್ಲಿ ಹೆಣ್ಣಾಗಿ\nಹುಟ್ಟಿ ನರಕಾಸುರನ ಸೆರೆಮನೆಯಲ್ಲಿ ಸಿಕ್ಕಿ ಒದ್ದಾಡಿದವರು. ಕೃಷ್ಣ ಅವರನ್ನು ಮದುವೆಯಾಗಿ ಉದ್ದರಿಸಿದ.\n\nನಂದಗೋಪ ಮತ್ತು ಯಶೋದೆ ಇವರು ಮೂಲತಃ ದೇವಾಂಶ ಸಂಭೂತರು. 'ದ್ರೋಣ' ನಾಮಕ ವಸು\nನಂದಗೋಪ ಮತ್ತು 'ಧರ' ನಾಮಕ ವಸುಪತ್ನಿ ಯಶೋದೆ. ಅವರು ಭೂಮಿಯಲ್ಲಿ ವೈಶ್ಯರಾಗಿ ಹುಟ್ಟಿದರು.\nಭಗವಂತ ತನ್ನ ಅವತಾರದಲ್ಲಿ ಅವರ ಮನೆಯಲ್ಲಿ ಬೆಳೆದು ಅವರನ್ನು ಉದ್ದರಿಸಿದ.\nಮಹಾ ಚೇತನ ವಿಧುರ. ಈತ ಸ್ವಯಂ ಧರ್ಮರಾಯ. ವೇದವ್ಯಾಸರ ಮಗನಾಗಿದ್ದರೂ ಕೂಡಾ ಶಾಪದ\nಫಲವಾಗಿ “ಕೆಲಸದವಳ ಮಗ' ಎಂದು ಹೇಳಿಸಿಕೊಂಡು ಬದುಕಬೇಕಾಗಿ ಬಂತು. ಸಂಧಾನಕ್ಕೆ ಬಂದ ಕೃಷ್ಣ-\nದುರ್ಯೋಧನ, ಭೀಷ್ಮ, ದ್ರೋಣರ ಮನೆಗೆ ಹೋಗದೆ ನೇರವಾಗಿ ವಿಧುರನ ಮನೆಗೆ ಬಂದು ಅಲ್ಲಿ ವಿಧುರನಿಂದ\nಸರಳ ಸತ್ಕಾರ ಸೇವಿಸಿ ಆತನನ್ನು ಪ್ರಸನ್ನನಾಗಿ ಮಾಡಿದ. ಇಲ್ಲಿ ಭಗವಂತ ಬಯಸುವುದು ಪ್ರದರ್ಶನವನ್ನಲ್ಲ\nಬದಲಿಗೆ ಪ್ರೀತಿಯನ್ನು ಎನ್ನು ವುದು ಸ್ಪ ಷ್ಟ ವಾಗುತ್ತದೆ. ಆತನಿಗೆ ಅಂತರಾತ್ಮ ಮುಖ್ಯ, ಮುಖವಾಡವಲ್ಲ.\nಹೀಗೆ ಕೃಷ್ಣ ಸ್ಟ ಷ್ಟ ವಾಗಿ. ಹೇಳುತ್ತಾನೆ. “ಯಾವುದೋ ಪಾಪ ಕರ್ಮದಿಂದ ಅಥವಾ ಶಾಪದಿಂದ\nಹೀನಯೋನಿಯಾಗಿ ಹುಟ್ಟಿದವರು ನನ್ನನ್ನು ಆಶ್ರಯಿಸಿದಾಗ ಪಾಪದಿಂದ ಕಳಚಿಕೊಂಡು ನನ್ನನ್ನು ಸೇರುತ್ತಾರೆ”\nಎಂದು.\n",
  "9.33": "ಕಿಮ್‌ ಪುನಃ ಬ್ರಾಹ್ಮಣಾಃ ಪುಣ್ಯಾಃ ಭಕ್ತಾಃ ರಾಜ ಋಷಯಃ ತಥಾ |\n\nಅನಿತ್ಯಮ್‌ ಅಸುಖಮ್‌ ಲೋಕಮ್‌ ಇಮಮ್‌ ಪ್ರಾಪ್ಯ ಭಜಸ್ವ ಮಾಮ್‌ -- ಪುಣ್ಯದ ಫಲದಿಂದ ಬ್ರಾಹ್ಮಣರಾಗಿ,\nಖುಷಿಗಳಂತಹ ಅರಸರಾಗಿ ಹುಟ್ಟಿ ಬಂದು ಭಕ್ತಿ ಮಾಡುವವರ ಬಗೆಗೆ ಹೇಳುವುದೇನು? ಅದರಿಂದ ಸ್ಥಿರವಲ್ಲದ,\nಸುಖವಿಲ್ಲದ ನರಜನ್ಮ ಬಂದಾಗ ನನ್ನನ್ನು ಆರಾಧಿಸು.\n\n“ಪುಣ್ಯದ ಫಲದಿಂದ ರಾಜರ್ಷಿಗಳಾಗಿ, ಬ್ರಹ್ಮಜ್ಞಾನಿಗಳಾಗಿ ಹುಟ್ಟಿ ಭಗವಂತನನ್ನು ಆರಾಧಿಸುವವರ ಬಗೆಗೆ\nವಿಶೇಷವಾಗಿ ಹೇಳಬೇಕೇನು?” ಎಂದು ಪ್ರಶ್ನಿಸುತ್ತಾನೆ ಕೃಷ್ಣ. ಹೀಗೆ ಭಗವಂತನಲ್ಲಿ ಶರಣಾಗಿ ಆಶ್ರಯ ಬೇಡುವ\nಪ್ರತಿಯೊಬ್ಬರ ರಕ್ಷಣೆಯ ಭಾರ ಭಗವಂತನದ್ದು. ಅದಕ್ಕಾಗಿ ಕೃಷ್ಣ ಇಲ್ಲಿ ನಮಗೆ ಕಿವಿ ಮಾತನ್ನು ಹೇಳುತ್ತಾನೆ:\n“ನೀನು ಈ ಪ್ರಪಂಚವೇ ಸರ್ವಸ್ವ ಎಂದು ಪ್ರಪಂಚದಲ್ಲಿ ಬಿದ್ದು ಒದ್ದಾಡಬೇಡ. ಏಕೆಂದರೆ ಇದು 'ಅನಿತ್ಯಮ್‌\nಅಸುಖಮ್‌ ಲೋಕಮ್‌\". ಇದರಲ್ಲಿ ಸುಖವಿಲ್ಲ. ಇದು ಶಾಶ್ವತವಲ್ಲ. ಆದ್ದರಿಂದ ಶಾಶ್ವತವಾದ ಆನಂದವನ್ನು\nಪಡೆಯುವುದಕ್ಕೋಸ್ಕರ ನನ್ನನ್ನು ಆಶ್ರಯಿಸು. ನನಗೆ ಶರಣಾಗು. ನಿನ್ನನ್ನು ಉದ್ಧಾರ ಮಾಡುವ ಹೊಣೆ ನನ್ನದು”.\n",
  "9.34": "ಮತ್‌ ಮನಾಃ ಭವ ಮತ್‌ ಭಕ್ತಃ ಮತ್‌ ಯಾಜೀ ಮಾಮ್‌ ನಮಸ್ಕುರು |\nಮಾಮ್‌ ಏವ ಏಷ್ಯಸಿ ಯುಕ್ತ್ವಾ ಏವಮ್‌ ಆತ್ಮಾನಮ್‌ ಮತ್‌ ಪರಾಯಣಃ -ನನ್ನಲ್ಲೇ ಬಗೆಯಿಡು. ನನ್ನನ್ನು ಅತಿಶಯವಾಗಿ ಪ್ರೀತಿಸು. ನನ್ನನ್ನೇ ಆರಾಧಿಸು. ನನಗೆ ತಲೆಬಾಗು. ಬಗೆಯನ್ನು ಹೀಗೆ ಅಣಿಗೊಳಿಸಿ ನನಗೆ ಮೊರೆ ಹೊಕ್ಕಾಗ ನನ್ನನ್ನೇ ಸೇರುವೆ.\n\nಹೇಳುವಂತೆ “ತ್ವನ್ಮಾ ಭಜಸ್ವ ಪದ್ಮಾಕ್ಷಿ, ಯೇನ ಸೌಖ್ಯಂ ಲಭಾಮ್ಯಹಮ್‌”, ನಾನು ನಿನ್ನನ್ನು ಭಜನೆ ಮಾಡುತ್ತೇನೆ, ನೀನು ನನ್ನನ್ನು ಭಜನೆ ಮಾಡು”. ಇಲ್ಲಿ ಭಜನೆ ಎಂದರೆ ಭಕ್ತಿಯಿಂದ ಪ್ರೀತಿಸುವುದು.\n\nನೀನು ಏನು ಪೂಜೆ ಮಾಡುತ್ತೀಯೋ ಅದು ಭಗವಂತನ ಪೂಜೆಯಾಗಿರಲಿ, ನಿನ್ನ ಎಲ್ಲಾ ಪ್ರೀತಿಯಲ್ಲಿ ಭಗವಂತನನ್ನು ಕಾಣು. ನೀನು ಮಾಡುವ ಎಲ್ಲಾ ನಮಸ್ಕಾರ ಭಗವಂತನ ನಮಸ್ಕಾರವಾಗಿರಲಿ. ಹೀಗೆ ಮಾಡಿ ನಿನ್ನ ಮನಸ್ಸನ್ನು ಭಗವಂತನಲ್ಲಿ ನೆಲೆಗೊಳಿಸಿ ಇಡಿಯ ಬದುಕನ್ನು ಭಗವನ್ಮಯ ಮಾಡಿಕೋ- ನಿನಗೆ ಎಲ್ಲಕ್ಕಿಂತ ದೊಡ್ಡ ವಸ್ತು ಭಗವಂತ, ಬದುಕಿನ ಸಾರ ಸರ್ವಸ್ವ ಭಗವಂತ, ನಿರಂತರ ಚಿಂತನೆಯ ವಸ್ತು ಭಗವಂತನಾಗಲಿ. ನಿನ್ನ ಬದುಕಿನ ಒಂದೊಂದು ಕ್ರಿಯೆಯೂ ಭಗವಂತನ ಆರಾಧನೆಯಾಗಲಿ. ಆಗ “ನೀನು ನನ್ನನ್ನು ಸೇರಲೇ ಬೇಕು” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಹೀಗೆ ಮೋಕ್ಷ ಸಾಧಕವಾದ ಉಪಾಸನೆಯನ್ನು ಕೃಷ್ಣ ವಿವರಿಸಿದ ಅನ್ನುವಲ್ಲಿಗೆ ಒಂಬತ್ತನೆಯ ಅಧ್ಯಾಯ ಮುಕ್ತಾಯವಾಯಿತು.\n\nಇತಿ ನವಮೋಽಧ್ಯಾಯಃ\nಒಂಬತ್ತನೆಯ ಅಧ್ಯಾಯ ಮುಗಿಯಿತು",
  "10.1": "ಅಧ್ಯಾಯ ಹತ್ತು\n\nನಾವು ಉಪಾಸನೆ ಮಾಡಬೇಕಾದ ಭಗವಂತನ ಗುಣವನ್ನು, ಜ್ಞಾನ ವಿಜ್ಞಾನವನ್ನು ಅರ್ಜುನನಿಗೆ ವಿವರಿಸಿದ ಕೃಷ್ಣ, ಆತನಲ್ಲಿ ಅರಳಿದ ಜ್ಞಾನ ತೃಷೆಯನ್ನು, ಪೂರ್ಣ ನಿಷ್ಠೆಯನ್ನು ಗುರುತಿಸಿ-ವಿಶೇಷವಾಗಿ ಉಪಾಸನೆಯಲ್ಲಿ ಅಳವಡಿಸಿಕೊಳ್ಳಬೇಕಾದ ಅನುಸಂಧಾನವನ್ನು, ಭಗವಂತನ ವಿಭೂತಿಯನ್ನು ಈ ಅಧ್ಯಾಯದಲ್ಲಿ ವಿವರಿಸುತ್ತಾನೆ.\n\nಸಾಮಾನ್ಯವಾಗಿ ಅಮೂಲ್ಯ ವಿದ್ಯೆಯನ್ನು ಗುರು ಸುಲಭವಾಗಿ ಬಹಿರಂಗಗೊಳಿಸುವುದಿಲ್ಲ. ಶಿಷ್ಯ ಗುರುವಿನಲ್ಲಿ ಪೂರ್ಣ ನಿಷ್ಠೆ ತೋರಿದಾಗ, ಆತನಲ್ಲಿ ಯೋಗ್ಯತೆ ಇದ್ದಾಗ ಮಾತ್ರ ಅಂತಹ ವಿಚಾರವನ್ನು ಬಿಚ್ಚಬೇಕು ಎನ್ನುತ್ತದೆ ಶಾಸ್ತ್ರ. ಹೀಗಾಗಿ ಗುರು ತನ್ನ ಶಿಷ್ಯನನ್ನು ಪರೀಕ್ಷೆ ಮಾಡದೆ ಅಮೂಲ್ಯ ವಿಚಾರವನ್ನು ಆತನಿಗೆ ಹೇಳುವುದಿಲ್ಲ. ಇದಕ್ಕೆ ಉತ್ತಮ ದೃಷ್ಟಾಂತವನ್ನು ಪ್ರಶ್ನೋಪನಿಷತ್ತಿನಲ್ಲಿ ಕಾಣಬಹುದು. ಪಿಪ್ಪಲಾದನ ಹತ್ತಿರ ಬಂದ ಆರು ಮಂದಿ ಮಹಾನ್‌ ವಿದ್ವಾಂಸರನ್ನು ಕುರಿತು ಆತ ಹೀಗೆ ಹೇಳುತ್ತಾನೆ:\n\nಭೂಯ ಏವ ತಪಸಾ ಬ್ರಹ್ಮಚರ್ಯೇಣ ಶ್ರದ್ಧಯಾ ಸಂವಸ್ಸರಂ ಸಂವತ್ಸೃಥ;\nಯಥಾಕಾಮಂ ಪ್ರಶ್ನಾನ್‌ ಪೈಚ್ಛತ; ಯದಿ ವಿಜ್ಞಾಸ್ಯಾಮಃ ಸರ್ವಂ ಹವೋ ವಕ್ಷ್ಯಾಮ ಇತಿ |೨|\n\n“ಒಂದು ವರ್ಷ ತಪಸ್ಸಿನಿಂದಲೂ ಬ್ರಹ್ಮಚರ್ಯದಿಂದಲೂ ಶ್ರದ್ಧೆಯಿಂದ ವಾಸಮಾಡಿರಿ. ಒಂದು ವರ್ಷದ ನಂತರ ನಿಮ್ಮ ಇಚ್ಛಾನುಸಾರ ಪ್ರಶ್ನೆ ಕೇಳಿ. ನನಗೆ ಗೊತ್ತಿದ್ದರೆ ಉತ್ತರಿಸುತ್ತೇನೆ” ಎಂದು. ಇಲ್ಲಿ ಗುರು ಮತ್ತು ಶಿಷ್ಯರ ಪರಸ್ಪರ ಪರೀಕ್ಷೆ ಎದ್ದು ಕಾಣುತ್ತದೆ. ಆದರೆ ಗುರು ತನ್ನ ಯೋಗ್ಯ ಶಿಷ್ಯನಲ್ಲಿ ಪೂರ್ಣ ನಿಷ್ಠೆಯನ್ನು ಗುರುತಿಸಿದಾಗ, ಆತ ಪ್ರಶ್ನಿಸದಿದ್ದರೂ ಕೂಡಾ ಸಂತೋಷದಿಂದ ತನ್ನಲ್ಲಿರುವ ಜ್ಞಾನವನ್ನು ಆತನಿಗೆ ಧಾರೆಯೆರೆಯುತ್ತಾನೆ. ಈ ಹಂತದಲ್ಲಿ ಕೃಷ್ಣ ಅರ್ಜುನನಲ್ಲಿ ಕಂಡಿದ್ದು ಇಂತಹ ಪೂರ್ಣನಿಷ್ಠೆ.\n\nಭಗವಾನುವಾಚ ।\nಭೂಯ ಏವ ಮಹಾಬಾಹೋ ಶೃಣು ಮೇ ಪರಮಂ ವಚಃ ।\nಯತ್‌ ತೇಹಂ ಪ್ರೀಯಮಾಣಾಯ ವಕ್ಷ್ಯಾಮಿ ಹಿತಕಾಮ್ಯಯಾ॥೧॥\n\nಭಗವಾನ್‌ ಉವಾಚ -ಭಗವಂತ ಹೇಳಿದನು:\n\nಭೂಯಃ ಏವ ಮಹಾಬಾಹೋ ಶೃಣು ಮೇ ಪರಮಮ್‌ ವಚಃ ।\n\nಯತ್‌ ತೇ ಅಹಮ್‌ ಪ್ರೀಯಮಾಣಾಯ ವಕ್ಷ್ಯಾಮಿ ಹಿತ ಕಾಮ್ಯಯಾ- ಓ ಮಹಾವೀರ, ಇನ್ನೂ ಕೇಳು ನನ್ನ ಹಿರಿನುಡಿಯನ್ನು, ಏಕೆಂದರೆ ಕೇಳಿ ಖುಷಿಪಡುತ್ತಿರುವ ನಿನಗೆ ಒಳಿತನ್ನು ಬಯಸಿಯೆ ನಾನು ಹೇಳುತ್ತಿದ್ದೇನೆ.\n\nಗುರುವಿಗೆ ಜ್ಞಾನ ಕೊಡುವುದರಲ್ಲಿ ಅತೃಪ್ತಿ ಬರುವುದು ಶಿಷ್ಯನ ಪ್ರತಿಭೆ ಮತ್ತು ಗುಣ ವಿಶೇಷದಿಂದ. ಇಲ್ಲಿ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ನಿನಗೆ ಇನ್ನಷ್ಟು ಹೇಳುತ್ತೇನೆ” ಎಂದು. ಏಕೆಂದರೆ ಇಲ್ಲಿ ಹೇಳುವ ವಿಷಯ “ಪರಮಮ್‌ ವಚಃ” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಇಲ್ಲಿ 'ಪರಮಂ' ಎಂದರೆ ನಾವು ತಿಳಿದುಕೊಳ್ಳಬೇಕಾದ ವಿಷಯದಲ್ಲೇ ಶ್ರೇಷ್ಠವಾದ ವಿಷಯ. ಅದು ಎಲ್ಲಕ್ಕಿಂತ ಮಿಗಿಲಾದ ಪರತತ್ವದ ಅರಿವನ್ನು ಕೊಡತಕ್ಕ ಶ್ರೇಷ್ಠ ಜ್ಞಾನ. ಇಡೀ ಲೋಕಕ್ಕೆ ಉಪಕಾರವಾಗುವಂತಾದ್ದು . ಇದಕ್ಕಿಂತ ಮಿಗಿಲಾದ ಇನ್ನೊಂದು ಸಂಗತಿ ಇಲ್ಲ. “ನೀನು ಈ ಯುದ್ಧ ಭೂಮಿಯಲ್ಲಿ ನಿಂತು ಇದನ್ನು ಕೇಳಿ ಸಂತೋಷಪಡುತ್ತಿದ್ದೀಯ, ನಿನ್ನಲ್ಲಿ ಆ ಆನಂದ ಚಿಮ್ಮುತ್ತಿದೆ. ಅದಕ್ಕೋಸ್ಕರ, ಜಗತ್ತಿನ ಹಿತಕ್ಕೋಸ್ಕರ ಹೇಳುತ್ತೇನೆ ಕೇಳು” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.",
  "10.2": "ನಮೇ ವಿದುಃ ಸುರ ಗಣಾಃ ಪ್ರಭವಮ್‌ ನ ಮಹಾ ಋಷಯಃ |\n\nಅಹಮ್‌ ಆದಿಃ ಹಿ ದೇವಾನಾಮ್‌ ಮಹಾ ಋಷೀಣಾಮ್‌ ಚ ಸರ್ವಶಃ -ನನ್ನ ಆಳವನ್ನು : [ನಾನು ಜಗವನ್ನು\nನಿರ್ಮಿಸುವ ಬಗೆಯನ್ನು ] ದೇವತೆಗಳಾಗಲೀ, ಮಹರ್ಷಿಗಳಾಗಲೀ, ಅಥವಾ ಇನ್ಯಾರೂ ತಿಳಿದಿಲ್ಲ. ದೇವತೆಗಳಿಗೆ,\nಹಿರಿಯ ಖುಷಿಗಳಿಗೆ , ಎಲ್ಲರಿಗೂ ಮೂಲ ನಾನೇ ಅಲ್ಲವೆ?\n\nಕೃಷ್ಣ ಇಲ್ಲಿ ಒಂದು ಮೂಲಭೂತವಾದ ಸಂಗತಿಯನ್ನು ತಿಳಿಸುತ್ತಿದ್ದಾನೆ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ನನ್ನ ಪ್ರಭವವನ್ನು\nಮಹರ್ಷಿಗಳಿಂದ ಹಿಡಿದು ಬ್ರಹ್ಮಾದಿ ದೇವತೆಗಳೂ ತಿಳಿದಿಲ್ಲ” ಎಂದು. ಇಲ್ಲಿ 'ಪ್ರಭವ' ಎನ್ನುವ ಪದವನ್ನು ಮೂರು\nಅರ್ಥದಲ್ಲಿ ಬಳಸಲಾಗಿದೆ. ಪ್ರಭವ ಎಂದರೆ ಮೂಲ ಅಥವಾ ಹುಟ್ಟು; ಪ್ರಭವ ಎಂದರೆ ಸಾಮರ್ಥ್ಯ ಅಥವಾ\nಹಿರಿಮೆ; ಪ್ರಭವ ಎಂದರೆ ಜಗತ್ತಿನ ಉತ್ಪತ್ತಿ. “ನನ್ನ ಮೂಲ, ನನ್ನ ಮಹಿಮೆ ಮತ್ತು ನನ್ನಿಂದಾದ ಈ ಜಗತ್ತಿನ\nಹುಟ್ಟು-ನನ್ನನ್ನು ಸಾಕ್ಷಾತ್ಮರಿಸಿಕೊಂಡ ಮಹಾಜ್ಞಾನಿಗಳಿಂದ ಹಿಡಿದು, ನನ್ನ ಅಪರೋಕ್ಷ ಜ್ಞಾನ ಪಡೆದ ಬ್ರಹ್ಮಾದಿ\nದೇವತೆಗಳಿಗೂ ತಿಳಿದಿಲ್ಲ” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.\n",
  "10.3": "ಯಃ ಮಾಮ್‌ ಅಜಮ್‌ ಅನಾದಿಮ್‌ ಚ ವೇತ್ತಿ ಲೋಕ ಮಹಾ ಈಶ್ವರಮ್‌ |\n\nಅಸಮ್ಮೂಢಃ ಸಃ ಮರ್ತ್ಯೇಷು ಸರ್ವ ಪಾಪೈಃ ಪ್ರಮುಚ್ಯತೇ -ನಾನು ಹುಟ್ಟಿರದವನು. ಎಲ್ಲವನ್ನೂ ನಡೆಸುತ್ತಾ\nಎಲ್ಲದರ ಮೊದಲಿದ್ದವನು [ಪ್ರಾಣತತ್ವಕ್ಕೂ ಮೂಲಕಾರಣ]. ಎಲ್ಲಾ ಲೋಕಗಳ ಒಡೆಯರಿಗೂ ಹಿರಿಯೊಡೆಯ.\nಮನುಜರಲ್ಲಿ ಹೀಗೆ ನನ್ನನ್ನು ತಿಳಿದವನು ಮೋಹವಳಿದವನು. ಅವನು ಪಾಪಗಳಿಂದ ಪಾರಾಗುತ್ತಾನೆ.\n\nನಮ್ಮಲ್ಲಿ ಕೆಲವರಿಗೆ ಒಂದು ಪ್ರಶ್ನೆ ಬರುವುದಿದೆ. “ಸಕಲ ಜೀವಜಾತವನ್ನು ಭಗವಂತ ಸೃಷ್ಟಿ ಮಾಡಿದರೆ ಆತನನ್ನು\nಯಾರು ಸೃಷ್ಟಿ ಮಾಡಿದರು” ಎಂದು. ಒಂದು ವೇಳೆ ಭಗವಂತನನ್ನು ಇನ್ನೊಬ್ಬ ಸೃಷ್ಟಿ ಮಾಡುತ್ತಿದ್ದರೆ ನಾವು\nಈತನನ್ನು ದೇವರು ಎಂದು ಹೇಳಲಾಗುತ್ತಿರಲಿಲ್ಲ. ಕೃಷ್ಣನಿಗೆ ನಮ್ಮ ಸಂದೇಹ ಏನು ಎನ್ನುವುದು ಗೊತ್ತು.\nಅದಕ್ಕಾಗಿ ಆತ ಈ ಶ್ಲೋಕದಲ್ಲಿ ನಮ್ಮ ಪ್ರಶ್ನೆಗೆ ಉತ್ತರ ನೀಡಿದ್ದಾನೆ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ಯಃ ಮಾಮ್‌ ಅಜಮ್‌\nಅನಾದಿಮ್‌ ” ಎಂದು. ಇಲ್ಲಿ \"ಅಜ' ಎಂದರೆ ಹುಟ್ಟಿರದವನು. ಭಗವಂತ ಹುಟ್ಟು ಸಾವಿನಿಂದಾಚೆ ನಿಂತವನು.\nಅದಕ್ಕಾಗಿ ನಾವು ಹುಟ್ಟು -ಸಾವಿನಿಂದ ಪಾರಾಗಬೇಕಾದರೆ ಆತನನ್ನು ಉಪಾಸನೆ ಮಾಡಿ ಆತನನ್ನು ಸೇರಬೇಕು.\nಭಗವಂತ ಅನಾದಿ. ಇಲ್ಲಿ ಅನಾದಿ(ಅನ-ಆದಿ) ಎಂದರೆ: “ಸೃಷ್ಟಿಗೆ ಮೊದಲು ಪ್ರೇರಣೆ ಮಾಡುತ್ತಿದ್ದವ ಮತ್ತು ಸೃಷ್ಟಿ\nಮಾಡಿ ಈ ಸೃಷ್ಟಿಯಲ್ಲಿ ಸಮಸ್ತ ವ್ಯಾಪಾರವನ್ನು ನಿಯಂತ್ರಣ ಮಾಡತಕ್ಕ ಸರ್ವೋತ್ಕೃಷ್ಟ ಶಕ್ತಿ'.\n\nಭಗವಂತ 'ಲೋಕಮಹೇಶ್ವರಃ'. ಬ್ರಹ್ಮಾದಿ ಸಮಸ್ತ ದೇವತೆಗಳು-'ಲೋಕೇಶರು'. ಅವರನ್ನು ಹೆತ್ತ ಮಾತೆ ಲಕ್ಷ್ಮಿ-\n'ಲೋಕೇಶ್ವರಿ'. ಅವಳಿಗೂ ಮಹಾನ್‌-'ಲೋಕಮಹೇಶ್ವರ' ಆ ಭಗವಂತ. ಅವನಿಗಿಂತ ಮಹತ್ತಾದ ಇನ್ನೊಂದು\nತತ್ವವಿಲ್ಲ. ಆತ ಹುಟ್ಟು ಸಾವನ್ನು ಮೀರಿನಿಂತವ.\n\nಮಹರ್ಷಿಗಳು, ದೇವತೆಗಳು, ಎಲ್ಲರನ್ನೂ ಸೃಷ್ಟಿ ಮಾಡಿದವ ಆ ಭಗವಂತ. ಆದ್ದರಿಂದ ಇವರ್ಯಾರೂ ಆತನ\nಮಹಿಮೆಯ ತುದಿಯನ್ನು ಕಂಡಿಲ್ಲ. ಋಗ್ವೇದದಲ್ಲಿ ಒಂದು ಕಡೆ ಹೀಗೆ ಹೇಳುತ್ತಾರೆ: ನ ತೇ ವಿಷ್ಣೋ\nಜಾಯಮಾನೋ ನಾ ಜಾತೋ ದೇವ ಮಹಿಮ್ನಃ ಪರಮಂತಮಾಪ' ಎಂದು. ಹಿಂದೆ ಹುಟ್ಟಿದವರಾಗಲೀ,\nಮುಂದೆ ಹುಟ್ಟುವವರಾಗಲೀ, ಭಗವಂತನ ಮಹಿಮೆಯ ತುತ್ತ ತುದಿಯನ್ನು ತಿಳಿದಿಲ್ಲ, ತಿಳಿಯಲು ಸಾಧ್ಯವಿಲ್ಲ.\nಏಕೆಂದರೆ ಅದು ಅನಂತ.\n\nಈ ಪ್ರಪಂಚದ ಸೃಷ್ಟಿ ಹೇಗಾಯಿತು ಎನ್ನುವುದು ಕೂಡಾ ಯಾರಿಗೂ ತಿಳಿದಿಲ್ಲ. ಏಕೆಂದರೆ ಪ್ರಳಯ ಕಾಲದಲ್ಲಿ\nಎಲ್ಲವೂ ಭಗವಂತನ ಉದರದಲ್ಲಿ ನಿದ್ರಾವಸ್ತೆಯಲ್ಲಿದ್ದು, ಆ ನಂತರ ಸೃಷ್ಟಿ ಕಾಲದಲ್ಲಿ ಮೊತ್ತ ಮೊದಲಿಗೆ\nಚತುರ್ಮುಖನನ್ನು ಭಗವಂತ ಸೃಷ್ಟಿ ಮಾಡಿದ. ಆದ್ದರಿಂದ ಚತುರ್ಮುಖನ ಹುಟ್ಟಿಗಿಂತ ಮೊದಲೇ ಆರಂಭವಾದ\nಈ ಸೃಷ್ಟಿ ನಿರ್ಮಾಣವನ್ನು ಕಂಡವರ್ಯಾರೂ ಇಲ್ಲ. ಇದಕ್ಕಾಗಿ ಋಗ್ವೇದದಲ್ಲಿ “ಈ ಸೃಷ್ಟಿಯ ರಹಸ್ಯ ತಿಳಿದಿದ್ದರೆ\nಒಬ್ಬ ಜಾಣ ಮಗನಿಗೆ ತಿಳಿದಿರಬೇಕು” ಎನ್ನುತ್ತಾರೆ. ಆತನೇ ಭಗವಂತನ ಸೃಷ್ಟಿಯ ಮೊದಲ ಜೀವ-'ಚತುರ್ಮುಖ\nಬ್ರಹ್ಮ'. ಈ ಎಲ್ಲಾ ಕಾರಣದಿಂದ ಸಾಮಾನ್ಯ ಮಾನವರಾದ ನಾವು ಭಗವಂತನ ಪೂರ್ಣ ಮಹಿಮೆಯನ್ನು\nತಿಳಿಯಲು ಸಾಧ್ಯವೇ ಇಲ್ಲ. ಇದನ್ನು ಆಚಾರ್ಯರು ಹೀಗೆ ಹೇಳಿದ್ದಾರೆ: “ಬಹು ಚಿತ್ರ ಜಗತ್‌ ಬಹುದಾಕಾರಣಾತ್‌\nಪರಶಕ್ತಿರನಂತ ಗುಣಃ ಪರಮಃ” ಎಂದು. ಭಗವಂತನ ಸೃಷ್ಟಿಯ ಈ ಪ್ರಪಂಚವೇ ಇಷ್ಟೊಂದು\nಅದ್ಭುತವಾಗಿರುವಾಗ-ಆ ಸೃಷ್ಟಿಕರ್ತ ಅದೆಷ್ಟು ಅದ್ಭುತವಾಗಿರಬೇಕು. ಆದ್ದರಿಂದ ಭಗವಂತ ಅನಂತ ಎನ್ನುವ\nನಿಜವನ್ನರಿತು ಆತನನ್ನು ಉಪಾಸನೆ ಮಾಡುವುದೊಂದೇ ಮೋಕ್ಷ ಮಾರ್ಗ. ಭಗವಂತನ ಬಗ್ಗೆ ಈ ನಿಜವನ್ನು\nತಿಳಿದವ \"ಅಸಮ್ಮೂಢ'. ಆತ ಯಾವ ಭ್ರಮೆಗೂ ಒಳಗಾಗದೆ ಸದಾ ಎಲ್ಲರನ್ನು ಪ್ರೀತಿಸುತ್ತಾ ಎಲ್ಲರಲ್ಲೂ\nಭಗವಂತನನ್ನು ಕಾಣುತ್ತಿರುತ್ತಾನೆ. “ಈ ಸತ್ಯವನ್ನರಿತ ಸಾಧಕ ಸರ್ವ ಪಾಪಗಳಿಂದ ಪಾರಾಗುತ್ತಾನೆ”\nಎನ್ನುವುದು ಕೃಷ್ಣನ ಭರವಸೆ.",
  "10.4": "ಬುದ್ಧಿಃ ಜ್ಞಾನಮ್‌ ಅಸಮ್ಮೋಹಃ ಕ್ಷಮಾ ಸತ್ಯಮ್‌ ದಮಃ ಶಮಃ ।\n\nಸುಖಮ್‌ ದುಃಖಮ್‌ ಭವಃ ಅಭಾವಃ ಭಯಮ್‌ ಚ ಅಭಯಮ್‌ ಏವ ಚ -- ವಿವೇಕ[ಅಂತಃಕರಣ], ಅರಿವು,\nಕೆಟ್ಟದ್ದನ್ನು ಮಾಡಬಯಸದಿರುವುದು, ತಪ್ಪಿಗನ ಮೇಲೂ ರೇಗದಿರುವುದು, ದಿಟದ ನಡೆ, ಇಂದ್ರಿಯಗಳ ಹಿಡಿತ,\nಭಗವಂತನಲ್ಲಿ ನಿಷ್ಠೆ, ಸುಖ-ದುಃಖ, ಹುಟ್ಟು-ಸಾವು, ಭಯ-ಕೆಚ್ಚು ಈ ಎಲ್ಲಾ ಬಗೆಗಳೂ ನನ್ನಿಂದಲೇ\nಉಂಟಾಗುತ್ತವೆ.\n\nಭಗವಂತನ ಉಪಾಸನೆಯಲ್ಲಿ ನಾವು ತಿಳಿದಿರಬೇಕಾದ ಮುಖ್ಯವಾದ ವಿಚಾರವನ್ನು ಕೃಷ್ಣ ಇಲ್ಲಿ ವಿವರಿಸುತ್ತಾನೆ.\nನಮಗೆ ಬುದ್ಧಿ, ಜ್ಞಾನ, ಅಸಮ್ಮೋಹ, ಕ್ಷಮಾ, ಸತ್ಯಂ, ದಮಃ-ಶಮಃ -ಎಲ್ಲವನ್ನು ಕೊಡುವವನು ಆ ಭಗವಂತ.\nಕೆಲವರಿಗೆ ತಾವು ತುಂಬಾ ಬುದ್ಧಿವಂತರು ಎನ್ನುವ ಭ್ರಮೆ ಇರುತ್ತದೆ. ಆದರೆ ಆ ಬುದ್ಧಿಶಕ್ತಿಯನ್ನು ಕರುಣಿಸುವವ\nಭಗವಂತ ಎನ್ನುವ ಸತ್ಯವನ್ನು ಅವರು ತಿಳಿದಿರುವುದಿಲ್ಲ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ನಿನಗೆ ಬುದ್ಧಿ ಕೊಡುವವನೂ\nನಾನು, ಜ್ಞಾನ ಕೊಡುವವನೂ ನಾನು” ಎಂದು. ಇಲ್ಲಿ 'ಜ್ಞಾನ' ಎಂದರೆ ಒಂದು ವಸ್ತುವಿನ ಅರಿವು. “ಬುದ್ಧಿ' ಎಂದರೆ\nಏನು ಮಾಡಬೇಕು, ಏನು ಮಾಡಬಾರದು ಎನ್ನುವ ವಿವೇಕ. ನಮ್ಮಲ್ಲಿ ಬುದ್ಧಿ ಮತ್ತು ಜ್ಞಾನ ಎರಡೂ ಇದ್ದಾಗ\nಮಾತ್ರ ಅದು ಪೂರ್ಣ. ಜ್ಞಾನವಿದ್ದು ಬುದ್ಧಿ ಇಲ್ಲದಿದ್ದರೆ ವೇದ ನಮ್ಮಿಂದ ದೂರವಾಗುತ್ತದೆ. “ಆಚಾರ ಹೀನಂ ನ\nಪುನಂತಿ ವೇದಾಃ”-ಒಬ್ಬ ಮನುಷ್ಯ ಆಚಾರ ಹೀನನಾಗಿದ್ದರೆ ಅವನನ್ನು ಎಲ್ಲಾ ವೇದಗಳೂ ಕೈಬಿಡುತ್ತವೆ. ರೆಕ್ಕೆ\nಬಲಿತ ಹಕ್ಕಿಮರಿಗಳು ತಮ್ಮ ಗೂಡನ್ನು ಬಿಟ್ಟು ಹಾರಿ ಹೋದಂತೆ ವೇದವಿದ್ಯೆ ಅವನನ್ನು ಬಿಟ್ಟು ಹಾರಿ\nಹೋಗುತ್ತದೆ. ಆಚಾರವಂತನಾಗಿರಬೇಕು ಎಂದು ತಿಳಿದಿರುವುದು ಜ್ಞಾನ. ಆದರೆ ಯಾವುದು ಆಚಾರ-ಯಾವುದು\nಅನಾಚಾರ ಎನ್ನುವ ವಿವೇಕ ಪ್ರಜ್ಞೆ-ಬುದ್ಧಿ. ಬುದ್ಧಿ-ಜ್ಞಾನದ ಜೊತೆಗೆ ಯಾವುದೇ ಸಂಶಯವಿಲ್ಲದೆ ಸತ್ಯವನ್ನು\nತಿಳಿಯುವ ಗ್ರಹಣಶಕ್ತಿ 'ಅಸಮ್ಮೋಹ'. ಇವು ಬದುಕಿನಲ್ಲಿ ನಮಗೆ ಆಸರೆಯಾಗಿರುವ ಮೂರು ಮುಖ್ಯ\nಆಧಾರಸ್ಥಂಭಗಳು. ನಾವು ಇದನ್ನು ತಿಳಿದು ಆ ಭಗವಂತನನ್ನು ಉಪಾಸನೆ ಮಾಡಬೇಕು.\n\nನಾಲ್ಕನೇ ಗುಣ “ಕ್ಷಮಾ'. ಇದು ಅತ್ಯಂತ ದೊಡ್ಡ ಗುಣ. ಯಾರಾದರು ನಮ್ಮನ್ನು ಟೀಕೆ ಮಾಡಿದರೆ- ಆ ಟೀಕೆಯಲ್ಲಿ\nನಮ್ಮನ್ನು ನಾವು ತಿದ್ದಿಕೊಳ್ಳುವ ಅಂಶ ಇದ್ದರೆ ತಿದ್ದಿಕೊಳ್ಳುವುದು. ಇಲ್ಲದೇ ಅದು ಕೇವಲ ಅಸೂಯೆಯ\nಟೀಕೆಯಾಗಿದ್ದರೆ ಯಾವುದೇ ಪ್ರತೀಕಾರವಿಲ್ಲದೆ ವಿಷಯವನ್ನು ಅಲ್ಲೇ ಬಿಟ್ಟುಬಿಡುವುದು “ಕ್ಷಮಾ”.\n\nಐದನೇ ಗುಣ 'ಸತ್ಯಂ'. ಸತ್ಯಮ್‌ ಎಂದರೆ ಪ್ರಾಮಾಣಿಕತೆ. ಇಂದು ನಾವು ಸಜ್ಜನಿಕೆಯನ್ನು ಮರೆತು ಸಜ್ಜೆನಿಕೆಯ\nಮುಖವಾಡದಲ್ಲಿ ಬದುಕುತ್ತಿದ್ದೇವೆ. ಅಪ್ರಮಾಣಿಕತೆ ಎನ್ನುವುದು ನಮ್ಮ ಜೀವನವನ್ನು ಆವರಿಸಿಕೊಂಡುಬಿಟ್ಟಿದೆ.\nಪ್ರಾಮಾಣಿಕತೆ ಇಲ್ಲದೆ ಯಾವ ಆಚಾರ ಸಂಪತ್ತಿದ್ದರೂ ಉಪಯೋಗವಿಲ್ಲ. ಒಬ್ಬ ವ್ಯಕ್ತಿಯ ಎದುರೊಂದು ಮತ್ತು\nಹಿಂದೊಂದು ಮಾತನಾಡುವುದು ಅಪ್ರಮಾಣಿಕತೆ. ನಮಗೆ ಇನ್ನೊಬ್ಬ ವ್ಯಕ್ತಿಯ ವಿಚಾರ ಇಷ್ಟವಾಗದೆ ಇದ್ದಲ್ಲಿ\nಅವರಿಗೆ ಅದನ್ನು ನೇರವಾಗಿ ಹೇಳಬಹುದು ಅಥವಾ ಅವರಿಂದ ದೂರವಿರಬೇಕು. ನಮ್ಮಲ್ಲಿ ಪ್ರಾಮಾಣಿಕತೆ\n\nಎಲ್ಲಿಯ ತನಕ ಬೆಳೆಯುವುದಿಲ್ಲವೋ ಅಲ್ಲಿಯ ತನಕ ಯಾವ ಶಾಸ್ತ್ರವೂ ನಮ್ಮನ್ನು ಉದ್ಧಾರ ಮಾಡುವುದಿಲ್ಲ.\nನಾವು ನಮಗೆ ಇಂತಹ ಪ್ರಾಮಾಣಿಕತೆ ಕೊಡು ಎಂದು ಭಗವಂತನನ್ನು ಉಪಾಸನೆ ಮಾಡಬೇಕು.\nಆರನೆಯದಾಗಿ ದಮಾಃ. ಇದು ಇಂದ್ರಿಯಗಳಿಗೆ ಸಂಬಂಧಪಟ್ಟದ್ದು. ನಮ್ಮ ಇಂದ್ರಿಯಗಳು ನಾವು ಹೇಳಿದಂತೆ\nಕೇಳುವುದಿಲ್ಲ. ಅವು ನಮ್ಮನ್ನು ಬೇಡದ ಕಡೆ ಸೆಳೆಯುತ್ತವೆ. ಇದರಿಂದ ನೋಡಬಾರದ್ದನ್ನು ನೋಡುವುದು,\nಆಡಬಾರದ್ದನ್ನು ಆಡುವುದನ್ನು ನಾವು ಮಾಡುತ್ತೇವೆ. ಇಂತಹ ಇಂದ್ರಿಯನಿಗ್ರಹ ದಮಾಃ. ಇಂದ್ರಿಯ ನಿಗ್ರಹಕ್ಕೆ\nಇರುವ ಏಕಮಾತ್ರ ಮಾರ್ಗ ಭಗವಂತನಲ್ಲಿ ಶರಣಾಗತಿ.\n\nಏಳನೆಯ ಗುಣ ಶಮಾಃ. ನಮ್ಮ ಮನಸ್ಸು ಶಾಂತವಾಗಿರುವುದು(to be in blissful state) ಶಮಾಃ. ಇಂದು\nನಾವೆಲ್ಲರೂ ಬದುಕುತ್ತಿರುವುದು ಅಶಾಂತಿ(Tension)ಯಿಂದಲೇ! ಇದಕ್ಕೆ ಮೂಲ ಕಾರಣ ನಾವು ನಮ್ಮ\nಮನಸ್ಸನ್ನು ಲೌಕಿಕ ವಿಚಾರದಲ್ಲಿ ಕೇಂದ್ರೀಕರಿಸಿ ಸಾಗುತ್ತಿರುವುದು. ಲೌಕಿಕ ವಿಚಾರವನ್ನು ಬಿಟ್ಟು, ಮನಸ್ಸನ್ನು\nಭಗವಂತನ ಕಡೆಗೆ ಹರಿಸಿದಾಗ ಮನಸ್ಸು ಹಾಯಾಗುತ್ತದೆ. ಜೀವನದಲ್ಲಿ ಸಮಸ್ಯೆ ಬಂದರೆ “ದೇವರಿದ್ದಾನೆ, ಆತ\nಬಿಟ್ಟು ಹಾಕುವುದಿಲ್ಲ” ಎನ್ನುವ ದೃಢನಂಬಿಕೆ ಉಳ್ಳವ ಈ ಸ್ಥಿತಿಯನ್ನು ಗಳಿಸಬಲ್ಲ. ಒಟ್ಟಿನಲ್ಲಿ 'ನಮ್ಮ ಒಳಪ್ರಪಂಚದ\nಸರ್ವಸ್ವವೂ ಭಗವಂತ ಎನ್ನುವ ಪರಿಜ್ಞಾನದಿಂದ ನಾವು ಉಪಾಸನೆ ಮಾಡಬೇಕು'-ಎನ್ನುವುದು ಇಲ್ಲಿರುವ\nಮೂಲ ಸಂದೇಶ.\n\nಮುಂದುವರಿದು ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಸುಖ-ದುಃಖ, ಹುಟ್ಟು-ಸಾವು, ಭಯ-ಕೆಚ್ಚ",
  "10.5": "ಅಹಿಂಸಾ ಸಮತಾ ತುಪ್ಪಿಃ ತಪಃ (ಅ)ದಾನಮ್‌ ಯಶಃ ಅಯಶಃ ।\nಭವಂತಿ ಭಾವಾಃ ಭೂತಾನಾಮ್‌ ಮತ್ತಃ ಏವ ಪೃಥಕ್‌ ವಿಧಾಃ -- ಅಹಿಂಸೆ, ಸಮದೃಷ್ಟಿ, ತೃಪ್ತಿ, ತಪಸ್ಸು,\n(ಅ)ದಾನ, (ಕೆಟ್ಟ)ಹೆಸರು- ಬಗೆ ಬಗೆಯ ಈ ಎಲ್ಲಾ ಬಗೆಗಳೂ ನನ್ನಿಂದಲೇ ಉಂಟಾಗುತ್ತವೆ.\n\nಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಅಹಿಂಸೆ, ಸಮದೃಷ್ಟಿ, ತೃಪ್ತಿ, ತಪಸ್ಸು, (ಅ)ದಾನ, ಹೆಸರು, ಕೆಟ್ಟ ಹೆಸರು” ಇವು ನನ್ನಿಂದ\nಎಂದು. ಇಲ್ಲಿ ಅಹಿಂಸೆ ಮತ್ತು ಸಮದೃಷ್ಟಿ ತುಂಬಾ ವಿಶೇಷವಾದುದ್ದು. ಏಕೆಂದರೆ ಹಿಂಸೆಯೂ ಕೆಲವೊಮ್ಮೆ\nಅಹಿಂಸೆಯಾಗುತ್ತದೆ ಮತ್ತು ಅಸಮಾನತೆಯೂ ಸಮಾನತೆಯಾಗುತ್ತದೆ. ಅದಕ್ಕಾಗಿ ಇದನ್ನು ಇಲ್ಲಿ ವಿಶೇಷವಾಗಿ\nಪ್ರಸ್ತಾಪಿಸಿದ್ದಾನೆ ಕೃಷ್ಣ.\n\nಮೊದಲಿಗೆ ಅಹಿಂಸೆ: ಇನ್ನೊಬ್ಬರಿಗೆ ತೊಂದರೆಯಾಗದಂತೆ ಬದುಕುವುದು ಅಹಿಂಸೆ. ಇಲ್ಲಿ ಅಹಿಂಸೆ ಎಂದರೆ\nಕೇವಲ ಶಾರೀರಿಕವಾಗಿ ಮಾತ್ರವಲ್ಲ, ಮನಸ್ಸು ಮತ್ತು ಮಾತಿನಲ್ಲೂ ನಾವು ಅಹಿಂಸೆಯನ್ನು ಸಾಧಿಸಬೇಕು.\nಉದಾಹರಣೆಗೆ: ಒಬ್ಬರನ್ನು ಚುಚ್ಚು ಮಾತಿನಿಂದ ಹಂಗಿಸುವುದು, ಮಾನಸಿಕವಾಗಿ ಇನ್ನೊಬ್ಬರನ್ನು\nನಿಂದಿಸುವುದು ಅಥವಾ ಶಾಪ ಹಾಕುವುದು ಕೂಡಾ ಹಿಂಸೆ. ಕೆಲವೊಮ್ಮೆ ಹಿಂಸೆಯೇ ಅಹಿಂಸೆಯಾಗುತ್ತದೆ.\nಉದಾಹರಣೆಗೆ: ಒಂದು ನರಭಕ್ಷಕ ಹುಲಿಯನ್ನು ಕೊಲ್ಲುವುದರಿಂದ ಊರಿನ ಅನೇಕ ಜನರ ಪ್ರಾಣ\nಉಳಿಯುವುದಾದರೆ ಅದನ್ನು ಕೊಲ್ಲುವುದು ಅಹಿಂಸೆ.(ನಾವು ಈ ರೀತಿಯ ಅಹಿಂಸೆಯನ್ನು ಕೃಷ್ಣನ ಅನೇಕ\nಕೃತಿಗಳಲ್ಲಿ ಕಾಣುತ್ತೇವೆ]. ದೊಡ್ಡ ಹಿಂಸೆಯನ್ನು ತಡೆಯುವುದಕ್ಕೋಸ್ಕರ ಮಾಡುವ ಚಿಕ್ಕ ಹಿಂಸೆ-ಅಹಿಂಸೆ. ನಾವು\nನಮ್ಮ ಮಾತಿನಿಂದ, ಕೃತಿಯಿಂದ ಮತ್ತು ಮನಸ್ಸಿನಿಂದ ಇನ್ನೊಬ್ಬರಿಗೆ ಹಿಂಸೆಯಾಗದಂತೆ ನಡೆದುಕೊಳ್ಳಬೇಕು.\nಎರಡನೇಯ ಗುಣ ಸಮದೃಷ್ಟಿ (ಸಮತಾಃ) : ಇಲ್ಲಿ ಸಮದೃಷ್ಟಿ ಎಂದರೆ ಎಲ್ಲರನ್ನೂ ಏಕ ರೂಪದಲ್ಲಿ ನೋಡುವುದು\nಎಂದರ್ಥವಲ್ಲ. ಇದು ಯೋಗ್ಯತೆಗನುಗುಣವಾದ ಸಮದೃಷ್ಟಿ. ಉದಾಹರಣೆಗೆ: ಒಂದು ಶಾಲೆಯಲ್ಲಿ ಚೆನ್ನಾಗಿ ಓದಿ\nಬರೆದ ವಿದ್ಯಾರ್ಥಿ ಹಾಗೂ ಓದದೇ ಪೋಲಿಯಾಗಿರುವ ಇನ್ನೊ ಬ್ಬ ವಿದ್ಯಾರ್ಥಿಗೆ ಸಮನಾದ ಅಂಕವನ್ನು\nಕೊಡುವುದು ಸಮಾನತೆ ಅಲ್ಲ. ಯಾವುದೇ ದ್ವೇಷವಿಲ್ಲದೆ, ಶತ್ರು, ಮಿತ್ರ, ಸ್ಥಳೀಯ, ಪರಕೀಯ ಎನ್ನುವ\nಭೇದವಿಲ್ಲದೆ, ಅವರವರ ಯೋಗ್ಯತೆಗೆ ತಕ್ಕಂತೆ ಅಂಕ ವಿತರಣೆ ಮಾಡುವುದು ಸಮಾನತೆ. ಯಾರನ್ನು ಹೇಗೆ\nನೋಡಬೇಕೋ ಅವರನ್ನು ಹಾಗೇ ನೋಡುವುದು. ತಂದೆಯನ್ನು ತಂದೆಯಂತೆ, ತಾಯಿಯನ್ನು ತಾಯಿಯಂತೆ,\nಗುರುವನ್ನು ಗುರುವಂತೆ. ಹೀಗೆ ಯಾರು ಸಮಾನರೋ ಅವರನ್ನು ಸಮಾನವಾಗಿ ಗೌರವಿಸುವುದು ಸಮದೃಷ್ಟಿ.\nಮೂರನೆಯ ಗುಣ ತೃಪ್ತಿ: ಮನುಷ್ಯನ ಎಲ್ಲಾ ದುಃಖಗಳಿಗೆ ಮುಖ್ಯ ಕಾರಣ ಅತೃಪ್ತಿ. ಇಂದಿನ ಸಮಾಜದಲ್ಲಿ ನಮ್ಮ\nಮನೆಯಲ್ಲಿ ನಮಗೆ ಅಗತ್ಯಕ್ಕೆ ಬೇಕಾದಷ್ಟು ಇದ್ದರೂ ಕೂಡಾ ಮಾಧ್ಯಮಗಳಲ್ಲಿ ಬರುವ ಜಾಹೀರಾತಿಗೆ\nಮರುಳಾಗಿ, ಅಥವಾ ನೆರಮನೆಯವರಿಗೆ ಪ್ರತಿಸ್ಪರ್ಧಿಯಾಗಿ, ಸದಾ ಅತೃಪ್ತಿಯಲ್ಲಿ ನಾವು ಬದುಕುತ್ತೇವೆ. ಕೆಲಸ\nಇಲ್ಲದಾಗ ಕೆಲಸದ ಆಸೆ, ನಂತರ ಎಷ್ಟು ಸಂಬಳ ಬಂದರೂ ಅಲ್ಲಿ ಅತೃಪ್ತಿ. ಇಲ್ಲದ್ದನ್ನು ಯೋಚಿಸಿ ಕೊರಗದೇ,\nಇದ್ದದ್ದನ್ನು ಯೋಚಿಸಿ ಖುಷಿ ಪಡುವುದು(Be content with whatever you have) ನಿಜವಾದ ತೃಪ್ತಿ.\nನಾಲ್ಕನೆಯದು ತಪಸ್ಸು: ಇದರಲ್ಲಿ ಮೂರು ಬಗೆ: ಕಾಯಾ-ವಾಚಾ-ಮನಸಾ ತಪಃ. ಕಾಯ ಅಂದರೆ ದೇಹ.\nದೇಹದ ಮೂಲಕ ತಪಸ್ಸು ಸಾಮಾನ್ಯವಾಗಿ ದೇಹ ಹೇಳಿದಂತೆ ಕೇಳದೇ ಇರುವುದು ಆಹಾರ ಅತ್ಯಯ ಅಥವಾ\nವ್ಯತ್ಯಯದಿಂದ. ಆಹಾರ ನಿಯಂತ್ರಣ ಮಾಡಿದಾಗ ಮನಸ್ಸು ನಿಯಂತ್ರಣಕ್ಕೆ ಬರುತ್ತದೆ. ಮನಸ್ಸು\nನಿಯಂತ್ರಣದಲ್ಲಿದ್ದರೆ ದೇಹ ಸ್ಥಿರವಾಗಿರಲು ಸಾಧ್ಯ. ಇದಕ್ಕಾಗಿ ನಾನಾ ರೀತಿಯ ನಿಯಂತ್ರಣ ಸಾಧನವಾದ\nವೃತಾನುಷ್ಠಾನ ಮಾಡುವುದು. ಒಟ್ಟಿನಲ್ಲಿ ಅಹಂಕಾರ ಅಸೂಯೆ ಪಡದೆ ಬಗ್ಗುವ ಗುಣ ಬರುವುದು. ದೇಹದ\nತಪಸ್ಸಿನಿಂದ. ಇನ್ನೊಬ್ಬರಿಗೆ ಹಿತವೆನಿಸುವ, ಸತ್ಯವಾದ-ಸಹಜ ಮಾತನ್ನಾಡುವುದು; ಶಾಸ್ತ್ರಗಳ ಶ್ರವಣ-ಮನನ\n\nಮಾಡಿ, ನಂತರ ಸ್ವಪ್ರವಚನದಿಂದ ಅಭ್ಯಸಿಸಿ ಅದನ್ನು ಅರಗಿಸಿಕೊಂಡು ಇನ್ನೊಬ್ಬರಿಗೆ ಪ್ರವಚನ ಮಾಡಿ,\nಮುಂದಿನ ತಲೆಮಾರಿಗೆ ಕೊಡುವುದು ವಾಚ-ತಪಃ. ಮಾನಸಿಕವಾಗಿ ಸದಾ ಆಳವಾದ ಚಿಂತನೆ ಮನಸಾ-ತಪಃ.\nಐದನೆಯದು (ಅ)ದಾನ: ದಾನ ಶಬ್ದಕ್ಕೆ ಸಂಸ್ಕೃತದಲ್ಲಿ ಎರಡು ಅರ್ಥವಿದೆ. ಒಂದು “ಕೊಡುವುದು' ಇನ್ನೊಂದು\n“ತುಂಡರಿಸುವುದು'. ಕೊಡುವುದರಿಂದ ಅದು ನಮ್ಮ ಪಾಪವನ್ನು ತುಂಡರಿಸಿದರೆ ಅದು ದಾನ. ಬದಲಿಗೆ ನಮ್ಮ\nಪುಣ್ಯವನ್ನು ತುಂಡರಿಸಿದರೆ ಅದು ಅದಾನ.\n\nನಮಗೆ ಅನುಪಯುಕ್ತವಾದ ವಸ್ತುವನ್ನು ಸಾಗಹಾಕುವುದಕ್ಕೋಸ್ಕರ ಕೊಡುವ ದಾನ ದಾನವಲ್ಲ. ಅತೀ\nಅಗತ್ಯವಾದ ವಸ್ತು ಇನ್ನೊಬ್ಬರಲ್ಲಿ ಇಲ್ಲದೇ ಅದು ನಮ್ಮಲ್ಲಿ ಇದ್ದರೆ, ನಮ್ಮಲ್ಲಿರುವುದನ್ನು ಅವರಿಗೆ ಹಂಚಿ ಅವರ\nಕೊರತೆ. ನೀಗಿಸುವುದು ನಿಜವಾದ ದಾನ. ಒಬ್ಬ ವ್ಯಕ್ತಿ ಒಂದು ಹೊತ್ತಿನ ಊಟಕ್ಕೇ ಗತಿ ಇಲ್ಲದೆ\nಪರದಾಡುತ್ತಿರುವಾಗ ನಮ್ಮಲ್ಲಿ ಎರಡು ಹೊತ್ತಿನ ಊಟಕ್ಕಾಗುವಷ್ಟು ಧಾನ್ಯವಿದ್ದರೆ, ನಮ್ಮ ನಾಳೆಯ ಬಗ್ಗೆ\nಯೋಚಿಸದೇ, ಆ ವ್ಯಕ್ತಿಗೆ ಒಂದು ಹೊತ್ತಿನ ಧಾನ್ಯವನ್ನು ದಾನ ಮಾಡುವುದು ನಿಜವಾದ ದಾನ.\n\nದಾನದಲ್ಲಿ ಅಶನ-ವಸನ-ಅನ್ನ ಇದನ್ನು ಯಾರಿಗೆ ಬೇಕಾದರೂ ದಾನ ಮಾಡಬಹುದು. ಇರುವುದಕ್ಕೆ ತಾಣ,\nಉಡುವುದಕ್ಕೆ ಬಟ್ಟೆ, ಹಸಿದವನಿಗೆ ಅನ್ನ. ಇದನ್ನು ಕೊಡುವುದಕ್ಕೆ ಯೋಗ್ಯ-ಅಯೋಗ್ಯ ಎನ್ನುವ ನಿರ್ಬಂಧವಿಲ್ಲ.\nಆದರೆ ಇತರೆ ವಸ್ತುವನ್ನು ದಾನ ಮಾಡುವಾಗ ಯಾವುದು ಯಾರಿಗೆ ಅಗತ್ಯ ಮತ್ತು ಯೋಗ್ಯ ಎಂದು ನೋಡಿ\nದಾನ ಮಾಡಬೇಕು. ಪ್ರಚಾರಕ್ಕಾಗಿ ದಾನ ಮಾಡುವುದು-ಅದಾನ. ಯಾವುದೇ ಬಯಕೆ ಇಲ್ಲದೆ ನಿಷ್ಟ ಎಹತೆಯಿಂದ\nಕರ್ತವ್ಯ ದೃಷ್ಟಿಯಿಂದ ಯೋಗ್ಯವಾದ ದೇಶದಲ್ಲಿ, ಯೋಗ್ಯವಾದ ಕಾಲದಲ್ಲಿ, ಯೋಗ್ಯವಾದ ವ್ಯಕ್ತಿಗೆ ಮಾಡುವ\nದಾನ ನಿಜವಾದ ದಾನ.\n\nಕೊನೆಯದಾಗಿ ಕೃಷ್ಣ ಯಶಃ-ಅಯಶಃ:ವನ್ನು ಇಲ್ಲಿ ಹೇಳಿದ್ದಾನೆ. ಇದು ತುಂಬಾ ವಿಚಿತ್ರವಾದದ್ದು. ಒಬ್ಬ ಕೆಟ್ಟದ್ದನ್ನು\nಮಾಡಿ ಒಳ್ಳೆಯವನು ಎಂದು ಯಶಸ್ಸನ್ನು ಗಳಿಸಬಹುದು. ಇನ್ನೊಬ್ಬ ಜೀವಮಾನವೆಲ್ಲ ಒಳ್ಳೆಯ ಕೆಲಸ ಮಾಡಿ\nಬೇಡವಾದ ಅಪವಾದ ಕೇಳಿ ದುರಂತಕ್ಕೊಳಗಾಗಬಹುದು. ಇದು ತೀರ್ಮಾನವಾಗುವುದು ನಮ್ಮ ಜೀವನದ\nನಡೆಯ ಮೇಲೆ. ಇದಕ್ಕಾಗಿ ಈ ವಿಷಯದ ಬಗ್ಗೆ ತಲೆ ಕೆಡಿಸಿಕೊಳ್ಳಬಾರದು. ಅಪವಾದ ಬಂದಾಗ ಹೇಗಿರಬೇಕು\nಎನ್ನುವುದನ್ನು ಕೃಷ್ಣ ತನ್ನ ಜೀವನ ಕ್ರಮದಲ್ಲಿ ನಮಗೆ ತೋರಿಸಿಕೊಟ್ಟಿದ್ದಾನೆ. ಶಮಂತಕ ಮಣಿಯನ್ನು ಕೃಷ್ಣ ಕದ್ದ\nಎನ್ನುವ ಅಪವಾದ ಕೃಷ್ಣನಿಗೆ ಬಂದಾಗ ಕೃಷ್ಣನ ನಡೆ ಇದಕ್ಕೆ ಉತ್ತಮ ದೃಷ್ಟಾಂತ.\n\nಹೀಗೆ “ಈ ಎಲ್ಲಾ ಭಾವಗಳು ಜೀವಜಾತಕ್ಕೆ ಬರುವುದು ನನ್ನಿಂದಲೆ” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಯಾರಿಗೆ ಯಾವ\nಕಾಲದಲ್ಲಿ ಯಾವ ಭಾವ ಬರಬೇಕು ಅನ್ನುವುದು ಭಗವಂತನ ನಿರ್ಧಾರ. ನಮ್ಮ ಮನಸ್ಸಿನ ಸ್ಥಿತಿಯ ಒಂದೊಂದು\nಚಲನ-ವಲನ ಭಗವಂತನ ಅಧೀನ. ಇದು ನಾವು ನಮ್ಮ ಉಪಾಸನೆಯಲ್ಲಿ ತಿಳಿದಿರಬೇಕಾದ ಮೂಲಭೂತ\nಸತ್ಯ. ಇದು ಕೃಷ್ಣ ಕೊಟ್ಟ ಮಾನಸಿಕ ಉಪಾಸನೆಯ ಅದ್ಭುತ ಚಿತ್ರಣ.\n",
  "10.6": "ಮಹರ್ಷಯಃ ಸಪ್ತ ಪೂರ್ವೇ ಚತ್ವಾರಃ ಮನವಃ ತಥಾ |\n\nಮತ್‌ ಭಾವಾಃ ಮಾನಸಾಃ ಜಾತಾಃ ಯೇಷಾಮ್‌ ಲೋಕೇ ಇಮಾಃ ಪ್ರಜಾಃ --ಮೊದಲ ಮನ್ವಂತರದ ಏಳು\nಮಂದಿ ಮಹರ್ಷಿಗಳು (ಮರೀಚಿ, ಅತ್ರಿ, ಅಂಗಿರಸ್‌, ಪುಲಸ್ಕೃ, ಪುಲಹ, ಕ್ರತು, ಮತ್ತು ವಸಿಷ್ಠ ], ಮೊದಲ ನಾಲ್ವರು\nಮನುಗಳು [ಸ್ವಾಯಂಭುವ, ಸ್ವಾರೋಚಿಷ, ಉತ್ತಮ ಮತ್ತು ರೈವತ], ಚತುರ್ಮುಖನ ಮಾನಸ ಪುತ್ರರಾದ\nಇವರು ನನ್ನಿಂದಲೇ ಆದವರು.[ನಾಲ್ಕು ವರ್ಣಗಳ ನಿಯಾಮಕರಾಗಿ ನಾಲ್ಕು ಪಂಗಡದಲ್ಲಿ ಸೇರಿದ, ವಿಶೇಷ\nಅರಿವಿನ ಕಾರಣ 'ಮನು'ಗಳೆನಿಸಿದ ಎಲ್ಲಾ ದೇವತೆಗಳು ನನ್ನಿಂದಲೇ ಆದವರು; ನನ್ನ ಇಚ್ಛೆಯಿಂದಲೇ ಹುಟ್ಟಿ\nಬಂದವರು.] ವಿಶ್ವದ ಈ ಜನರೆಲ್ಲಾ ಅವರದೇ ಸಂತತಿ.\n\nಇಡೀ ಬ್ರಹ್ಮಾಂಡ ಸೃಷ್ಟಿ ಭಗವಂತನಿಂದಾಯಿತು ಎನ್ನುವುದು ನಮಗೆ ತಿಳಿದಿದೆ. ಇಲ್ಲಿ ಕೃಷ್ಣ ನಾವು\nಉಪಾಸನೆಯಲ್ಲಿ ತಿಳಿದಿರಬೇಕಾದ ಮುಖ್ಯ ಅಂಶವನ್ನು ವಿವರಿಸುತ್ತಾನೆ. ಮೊದಲ ಮನ್ವಂತರದ ಸಪ್ಪರ್ಷಿಗಳು\nಮತ್ತು ಮೊದಲ ನಾಲ್ಕು ಮನುಗಳನ್ನು ಕೃಷ್ಣ ಇಲ್ಲಿ ಪ್ರಸ್ತಾಪಿಸಿದ್ದಾನೆ. ಪ್ರತಿಯೊಂದು ಮನ್ವಂತರಕ್ಕೂ ಬೇರೆ ಬೇರೆ\nಸಪ್ತರ್ಷಿಗಳಿದ್ದಾರೆ. ದೇವತಾ ತಾರತಮ್ಯದಲ್ಲಿ ಹದಿನಾರನೇ ಕಕ್ಷೆಯಲ್ಲಿ ಬರುವ ಮೊದಲ ಮನ್ವಂತರದ ಈ\nಸಪ್ತರ್ಷಿಗಳು ಖುಷಿಮಂಡಲದಲ್ಲೇ ಬಹಳ ಶ್ರೇಷ್ಠರು. ಪುರಾಣ ಮತ್ತು ಮಹಾಭಾರತದ ಮೋಕ್ಷಧರ್ಮ ಪರ್ವವನ್ನು\nನೋಡಿದಾಗ-ಇಲ್ಲಿ “ಮಹರ್ಷಯಃ ಸಪ್ತ ಪೂರ್ವೇ” ಎನ್ನುವುದು ಸೃಷ್ಟಿಕಾರಣನಾದ ಚತುರ್ಮುಖನಿಗೆ\nಸಹಾಯಕರಾದ ಸಪ್ತಬ್ರಹ್ಮರನ್ನೂ ಸೂಚಿಸುತ್ತದೆ ಎಂದು ತಿಳಿಯುತ್ತದೆ. [ಇಲ್ಲಿ ಉಪಲಕ್ಷಣವಾಗಿ ಭೃಗು ಮತ್ತು\nದಕ್ಷರನ್ನು ಸೇರಿಸಿಕೊಳ್ಳಬೇಕು. ಹತ್ತನೆಯವನಾದ ಮಾನಸ ಪುತ್ರ ನಾರದ ಬ್ರಹ್ಮಚಾರಿ. ಆದ್ದರಿಂದ ಸೃಷ್ಟಿ\nವಿಸ್ತಾರದಲ್ಲಿ ಆತನ ಹೆಸರನ್ನು ಸೇರಿಸಿಲ್ಲ... ಈ ಏಳುಮಂದಿ ಖುಷಿಗಳು ಮತ್ತು ಭೃಗು-ದಕ್ಷರನ್ನು\nಪ್ರಜಾಪತಿಗಳೆಂದು ಕರೆಯುತ್ತಾರೆ. ಭಗವಂತ ಚತುರ್ಮುಖನನ್ನು ಸೃಷ್ಟಿ ಮಾಡಿ, ಅವನ ಮೂಲಕ\nಸಪ್ತರ್ಷಿಗಳನ್ನು ಸೃಷ್ಟಿ ಮಾಡಿದ. ಸೃಷ್ಟಿಯಲ್ಲಿ ಮಾನವರ ವಂಶವಿಸ್ತಾರ ಮೊದಲು ಸ್ವಾಯಂಭುವ ಮನುವಿನ\nಮೂಲಕವಾಯಿತು. ಈತನಿಂದ ಮನು ವಂಶ ಬೆಳೆದುಬಂತು. ಈ ಎಲ್ಲಾ ಕಾರಣದಿಂದ ಮೊದಲ ನಾಲ್ಕು\nಮನ್ವಂತರದ ಅಧಿಪತಿಗಳು ಮತ್ತು ಸಪ್ಪರ್ಷಿಗಳು ಪ್ರಧಾನವಾಗಿ ಉಪಾಸನೆಯಾಗಬೇಕಾದ ಹಿಂದಿನವರು.\nವಿಶ್ವದ ಈ ಜನರೆಲ್ಲಾ ಅವರದೇ ಸಂತತಿ.\n\n'ಮನು' ಎನ್ನುವುದಕ್ಕೆ ಇನ್ನೊಂದು ಅರ್ಥವಿದೆ. ಭಗವಂತನ ಪರಿವಾರವಾದ ದೇವತೆಗಳನ್ನೂ 'ಮನುಗಳು'\nಎನ್ನುತ್ತಾರೆ. ತತ್ತ್ವಾಭಿಮಾನಿ ದೇವತೆಗಳಲ್ಲಿ ಮುಖ್ಯವಾಗಿ ನಾಲ್ಕು ವಿಧ. ಇವರು ಮನುಷ್ಯನ ನಾಲ್ಕು\nಸ್ವಭಾವವನ್ನುಬ್ರಾಹ್ಮಣ್ಯ, ಕ್ಷಾತ್ರ, ವೈಶ್ಯ, ಶೂದ್ರ) ನಿಯಂತ್ರಿಸುವ ದೇವತೆಗಳು. ನಮ್ಮಲ್ಲಿ ಪ್ರತಿಯೊಬ್ಬರಲ್ಲೂ ಈ\nನಾಲ್ಕು ಸ್ವಭಾವವಿರುತ್ತದೆ. ಯಾವ ಸ್ವಭಾವ ನಮ್ಮಲ್ಲಿ ಹೆಚ್ಚಾಗಿದೆಯೋ ನಾವು. ಆ ವರ್ಗದಿಂದ\nಕರೆಸಿಕೊಳ್ಳುತ್ತೇವೆ. ಇದಲ್ಲದೆ \"ಮನು' ಶಬ್ದವಾಚ್ಯ ಜೀವವರ್ಗ ನಾಲ್ಕು: ಸಮಸ್ತ ದೇವತೆಗಳು, ದೇವತೆಗಳಿಂದ\nಸೃಷ್ಟಿಯಾದ ಖುಷಿಗಳು(ಮಾನವರು), ಖುಷಿಪರಂಪರೆಯಿಂದ ಬಂದ “ಮಾನವಮಾನವರು', ಈ\nಪರಂಪರೆಯಿಂದ ಬಂದ ಮನುಷ್ಯರು. ಇದು ಉಪಾಸನೆಯಲ್ಲಿ ತಿಳಿದಿರಬೇಕಾದ ಅಂಶ.\n",
  "10.7": "ಏತಾಮ್‌ ವಿಭೂತಿಮ್‌ ಯೋಗಮ್‌ ಚ ಮಮ ಯಃ ವೇತ್ತಿ ತತ್ತ್ವತಃ |\nಸಃ ಅವಿಕಂಪೇನ ಯೋಗೇನ ಯುಜ್ಯತೇ ನ ಅತ್ರ ಸಂಶಯಃ --ನನ್ನ ಈ ಹಿರಿಮೆಯನ್ನು [ಸನ್ನಿಧಾನದಿಂದ\nಹಿರಿಮೆಯನ್ನೀಯುವ ನನ್ನ ರೂಪಗಳ ಬಗೆಯನ್ನು] ಮತ್ತು ಆಳವನ್ನು ಸರಿಯಾಗಿ ತಿಳಿದವನು ಪರಿಶುದ್ಧವಾದ\nಧ್ಯಾನಯೋಗದಲ್ಲಿ ನೆಲೆಗೊಳ್ಳುತ್ತಾನೆ. ಇದರಲ್ಲಿ ಸಂದೇಹವಿಲ್ಲ.\n\nಭಗವಂತನ ಹಿರಿಮೆಯನ್ನು, ಆತನ ವಿವಿಧ ರೂಪವನ್ನು, ಅದರ ಆಳವನ್ನು-ಯಥಾರ್ಥವಾಗಿ ತಿಳಿದರೆ ನಮಗೆ\nಸಹಜವಾಗಿ ಶರಣಾಗತಿ ಬರುತ್ತದೆ. ಭಗವಂತನ ಬಗೆಗಿನ ಜ್ಞಾನ ನಮ್ಮಲ್ಲಿ ದೃಢನಂಬಿಕೆಯನ್ನು ಹುಟ್ಟಿಸುತ್ತದೆ.\nಶ್ರದ್ಧೆ ಮತ್ತು ಭಕ್ತಿಯಿಂದ ತುಂಬಿದ ಮನಸ್ಸು ಭಗವಂತನಲ್ಲಿ ನೆಲೆನಿಲ್ಲುತ್ತದೆ.",
  "10.8": "ಅಹಮ್‌ ಸರ್ವಸ್ಯ ಪ್ರಭವಃ ಮತ್ತಃ ಸರ್ವಮ್‌ ಪ್ರವರ್ತತೇ ।\nಇತಿ ಮತ್ವಾ ಭಜಂತೇ ಮಾಮ್‌ ಬುಧಾಃ ಭಾವ ಸಮನ್ವಿತಾಃ ತಿಳಿದವರು “ನಾನು ಎಲ್ಲದರ ಮೂಲಕಾರಣ,\nನನ್ನಿಂದಲೇ ಎಲ್ಲವೂ ನಡೆಯುತ್ತಿದೆ' ಎಂದರಿತು ಭಕ್ತಿಯಿಂದ ನನ್ನ ನ್ನು ಸೇವಿಸುತ್ತಾರೆ.\n\nಜ್ಞಾನಿಗಳು “ಎಲ್ಲದರ ನಿಯಾಮಕ ಭಗವಂತ, ಎಲ್ಲವೂ ಭಗವಂತನಿಂದ ಸೃಷ್ಟಿಯಾಗಿದೆ, ಎಲ್ಲವೂ\nಭಗವಂತನಿಂದ ನಿಯತವಾಗಿದೆ' ಎನ್ನುವ ಸತ್ಯವನ್ನು ಅರಿತು ಭಕ್ತಿಯಿಂದ ಉಪಾಸನೆ ಮಾಡುತ್ತಾರೆ. “ಈ ರೀತಿ\nಭಗವಂತನ ಬಗೆಗೆ ಅನನ್ಯ ಭಕ್ತಿ ಮತ್ತು ಸರ್ವೋತ್ತಮ ಜ್ಞಾನವುಳ್ಳವರು: ತಮ್ಮೆಲ್ಲಾ ಮನ್ಸಸ್ಸಿನ ಪ್ರಪಂಚ ನನ್ನ\nಅಧೀನ, ಎಲ್ಲಕ್ಕೂ ಕಾರಣ ನಾನು, ಎಲ್ಲವೂ ಹುಟ್ಟಿದ್ದು ನನ್ನಿಂದ, ಎಲ್ಲವೂ ನಿಯಂತ್ರಿತವಾಗುವುದು ನನ್ನಿಂದ,\nಎಲ್ಲವೂ ನನ್ನ ಅಧೀನ ಎಂದು ತಿಳಿದು ಉಪಾಸನೆ ಮಾಡುತ್ತಾರೆ” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.\n",
  "10.9": "ಮತ್‌ ಚಿತ್ತಾಃ ಮತ್‌ ಗತ ಪ್ರಾಹಾಃ ಬೋಧಯಂತಃ ಪರಸ್ಪರಮ್‌ ।\nಕಥಯಂತಃ ಚ ಮಾಮ್‌ ನಿತ್ಯಮ್‌ ತುಷ್ಯಂತಿ ಚ ರಮಂತಿ ಚ --ಅನುಗಾಲ ನನ್ನಲ್ಲೇ ಬಗೆಯಿಟ್ಟವರು, ನನಗಾಗಿ\nಬದುಕುವವರು, ನನ್ನನ್ನೇ ಒಬ್ಬರಿಗೊಬ್ಬರು ತಿಳಿಹೇಳುತ್ತಾ, ತಿಳಿಯುತ್ತಾ ತಣಿಯುತ್ತಾರೆ; ಸಂತಸಪಡುತ್ತಾರೆ.\n\nಹೀಗೆ ನಿಜವಾದ ಜ್ಞಾನ ಭಕ್ತಿ ಉಳ್ಳವರ ಚಿತ್ತದಲ್ಲಿ ಸದಾ ಭಗವಂತನ ಚಿಂತನವೇ ತುಂಬಿರುತ್ತದೆ. ಅವರ ಮನಸ್ಸು\nಭಗವನ್ಮಯವಾಗಿ ಬಿಡುತ್ತದೆ. ಅವರಿಗೆ ಎಲ್ಲವುದರಲ್ಲೂ ಭಗವಂತನೇ ಕಾಣುತ್ತಾನೆ. ಇಂತವರು ಪ್ರತೀ ಘಟನೆಯ\nಹಿಂದೆ ಭಗವಂತನಿದ್ದಾನೆ, ಅವನ ಇಚ್ಛೆಯಂತೆ ಎಲ್ಲವೂ ನೆಡೆಯತ್ತಿದೆ ಎನ್ನುವ ಅರಿವಿನಲ್ಲಿ ಬದುಕುತ್ತಾರೆ. ಇವರ\nಮನಸ್ಸು ಭಗವಂತನೊಂದಿಗೆ ಶ್ರುತಿಗೂಡಿರುತ್ತದೆ. ಇವರು ಸದಾ ಭಗವಂತನ ಬಗೆಗೆ ಮಾತನಾಡುತ್ತಿರುತ್ತಾರೆ.\nಒಂದೊಂದು ಸಂಗತಿಯಲ್ಲೂ “ಭಗವಂತನ ಸೃಷ್ಟಿ ಎಷ್ಟು ಅದ್ಭುತ' ಎನ್ನುವಂತೆ ಇವರು ವಿಶ್ಲೇಷಣೆ ಮಾಡುತ್ತಾರೆ.\nತಮ್ಮ ಜೀವನದ ಪ್ರತಿಯೊಂದು ಘಟನೆಯನ್ನೂ ಇವರು ಭಗವಂತನ ಪ್ರಸಾದ ಎನ್ನುವಂತೆ ಸ್ವೀಕರಿಸುತ್ತಾರೆ.\nಇಂತವರ ಜೀವನ ಆನಂದಮಯವಾಗಿರುತ್ತದೆ. ಇವರಲ್ಲಿ ಕೆಟ್ಟ ಯೋಚನೆ ಸುಳಿಯುವುದಿಲ್ಲ. ಇವರ ಮನಸ್ಸು\nಸದಾ ನಿರ್ಮಲವಾಗಿರುತ್ತದೆ. ಇವರು ಲೋಕ ವ್ಯವಹಾರದ ಮಾತನ್ನು ಬಿಟ್ಟು, ಭಗವಂತನ ವಿಚಾರ\nಮಾತನಾಡುತ್ತಾ ಸದಾ ಆನಂದಪಡುತ್ತಿರುತ್ತಾರೆ.\n",
  "10.10": "ತೇಷಾಮ್‌ ಸತತ ಯುಕ್ತಾನಾಮ್‌ ಭಜತಾಮ್‌ ಪ್ರೀತಿ ಪೂರ್ವಕಮ್‌ ।\nದದಾಮಿ ಬುದ್ಧಿಯೋಗಮ್‌ ತಮ್‌ ಯೇನ ಮಾಮ್‌ ಉಪಯಾಂತಿ ತೇ -ನನ್ನಲ್ಲೇ ಅನುಗಾಲ ಬಗೆಯಿಟ್ಟು\nಪ್ರೀತಿಯಿಂದ ಸೇವಿಸುವವರಿಗೆ ಆ ತಿಳಿವಿನ ದಾರಿಯನ್ನು ಕರುಣಿಸುತ್ತೇನೆ. ಅದರಿಂದ ಅವರು ನನ್ನನ್ನೇ\n\nಸೇರುತ್ತಾರೆ.\n\nಈ ಶ್ಲೋಕದಲ್ಲಿ “ಸತತಯುಕ್ತಾನಾಂ” ಎನ್ನುವಲ್ಲಿ ಬರುವ 'ಯಕ್ತಿ' ಎನ್ನುವ ಶಬ್ದಕ್ಕೆ ಸಂಸ್ಕೃತದಲ್ಲಿ ಅನೇಕ\nಅರ್ಥಗಳಿವೆ. ಬಹಳ ಯೋಗ್ಯವಾದ ಆಚಾರನಿಷ್ಠೆ ಹೊಂದಿ, ದಾರಿತಪ್ಪದೆ, ಜಾರದೆ ಬದುಕುವುದು ಯುಕ್ತಿ,\nಭಗವಂತನ ಅನುಸಂಧಾನಕ್ಕೆ ಪೂರಕವಾದ ವೇದಾಧ್ಯಯನವನ್ನು ಗ್ರಹಿಸುವುದು ಯುಕ್ತಿ. ಭಗವಂತನಲ್ಲಿ\nಮನಸ್ಸನ್ನು ನೆಲೆಗೊಳಿಸುವುದು ಯುಕ್ತಿ. ಇಲ್ಲಿ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಯಾವ ಬುದ್ಧಿಯೋಗದಿಂದ ಭಗವಂತನನ್ನು\nಸೇರುವುದು ಸಾಧ್ಯವೋ, ಅಂತಹ ವಿಷಯ ಚಿಂತನೆ ಮಾಡುವ ಮನಸ್ಸು, ಭಕ್ತಿಯಿಂದ ಚಿಂತನೆ ಮಾಡಬೇಕು\nಎನ್ನುವ ಬುದ್ಧಿ, ನಿಶ್ಚಯವಾದ ಜ್ಞಾನವನ್ನು-ನಾನೇ ಕೊಡುತ್ತೇನೆ” ಎಂದು. ಭಗವಂತನಲ್ಲಿ ಶರಣಾಗಿ ಪ್ರೀತಿಯಿಂದ\nಅವನನ್ನು ಸೇವಿಸಿದಾಗ-ಭಗವಂತನನ್ನು ಸೇರುವ ಮಾರ್ಗವನ್ನು ಭಗವಂತನೇ ತೋರಿಸುತ್ತಾನೆ.\n",
  "10.11": "ತೇಷಾಮ್‌ ಏವ ಅನುಕಂಪಾರ್ಥಮ್‌ ಅಹಮ್‌ ಅಜ್ಞಾನ ಜಮ್‌ ತಮಃ ।\n\nನಾಶಯಾಮಿ ಆತ್ಮ ಭಾವ ಸ್ಥ ಜ್ಞಾನ ದೀಪೇನ ಭಾಸ್ವತಾ -ನಾನು ಅವರ ಮೇಲಣ ಕನಿಕರದಿಂದಲೇ, ಅವರ\nಬಗೆಯಲ್ಲಿ ನೆಲೆನಿಂತು, ಬೆಳಗುವ ಅರಿವಿನ ಪಂಜಿನಿಂದ ಅಜ್ಞಾನದಿಂದ ಕವಿದ ಕತ್ತಲನ್ನು ಹೋಗಲಾಡಿಸುತ್ತೇನೆ.\n\nಭಗವಂತ ನಮ್ಮನ್ನು ಉದ್ಧರಿಸುವುದು ಯಾವುದೋ ಸ್ವಾರ್ಥಕ್ಕಾಗಿ ಅಲ್ಲ. ಬದಲಿಗೆ ನಮ್ಮ ಮೇಲಿನ\nಕರುಣೆಯಿಂದ. ತನ್ನನ್ನು ಅನನ್ಯ ಭಕ್ತಿಯಿಂದ ಭಜಿಸಿ ಆರಾಧನೆ ಮಾಡುವ ಭಕ್ತನ ಮೇಲಿನ ಅನುಕಂಪದಿಂದ ಆತ\nನಮ್ಮನ್ನು ಉದ್ಧರಿಸುತ್ತಾನೆ. ಆತ ನಮಗೆ ಕೇವಲ ಬುದ್ಧಿ ಕೊಡುವುದಷ್ಟೇ ಅಲ್ಲ, ನಮ್ಮ ಬುದ್ಧಿಯನ್ನು ಸದಾ\nಕವಿದಿರುವ ತಮಸ್ಸಿನ(ಅಜ್ಞಾನದ) ಪೊರೆಯನ್ನು ಕಳಚುವವನೂ ಅವನೇ. ಭಗವಂತನ ಸಹಾಯವಿಲ್ಲದೆ ನಮ್ಮ\nಮನಸ್ಸು-ಬುದ್ಧಿಗೆ ಕವಿದಿರುವ ಅಜ್ಞಾನದ ಪೊರೆಯನ್ನು ನಾವೇ ನೀಗಿಸಿಕೊಳ್ಳಲು ಸಾಧ್ಯವಿಲ್ಲ. ತ್ರಿಗುಣಾತೀತ\nಭಗವಂತನೊಬ್ಬನೇ ಈ ಕತ್ತಲನ್ನು ಕಳೆಯಬಲ್ಲ. ಇದರಿಂದ ನಾವು ಯಥಾರ್ಥವನ್ನು ಯಥಾರ್ಥವಾಗಿ ಗ್ರಹಣ\nಮಾಡಬಹುದು. ಭಗವಂತ ನಮ್ಮ ಭಾವದಲ್ಲಿ-ಭಕ್ತಿಯಲ್ಲಿ ತುಂಬಿ, ನಮ್ಮ ಸ್ವರೂಪ ಜಾಗೃತಗೊಳಿಸಿ, ಕೃಪೆಯ\nದೃಷ್ಟಿ ಬೀರಿ, ಎಲ್ಲಾ ವಿಧದಿಂದ ಬೆಳಕು ನೀಡಿ, ಯಥಾರ್ಥವನ್ನು ಕಾಣುವಂತೆ ಮಾಡುತ್ತಾನೆ. ಇದಕ್ಕಾಗಿ\n“ನನ್ನೊಳಗಿನ ಕತ್ತಲನ್ನು ನೀಗು ಭಗವಂತ' ಎಂದು ನಾವು ಆತನಲ್ಲಿ ಶರಣಾಗಬೇಕು. ಒಳಗೆ ಕತ್ತಲನ್ನು\nಇಟ್ಟುಕೊಂಡು ಎಷ್ಟು ಅಧ್ಯಯನ ಮಾಡಿದರೂ ಉಪಯೋಗವಿಲ್ಲ. ಶಾಸ್ತ್ರ ಓದಿದಾಗ ಯಥಾರ್ಥ\nತಿಳಿಯಬೇಕಾದರೆ ಭಗವಂತನಲ್ಲಿ ಶರಣಾಗತಿ ಮುಖ್ಯ.\n\nಈ ಹಂತದಲ್ಲಿ ಅರ್ಜುನ ಕೃಷ್ಣನ ಉಪದೇಶ ಕೇಳಿ ಮೈಮರೆತು ಹೋದ. ಆತನಿಗೆ ತಾನು ಯುದ್ಧರಂಗದಲ್ಲಿ\nನಿಂತಿದ್ದೇನೆ ಎನ್ನು ವ ವಿಚಾರವೇ ಮರೆತು ಹೋಗಿ, ಕೇವಲ ಕೃಷ್ಣನೊಬ್ಬ ನೇ ಕಾಣಲಾರಂಭಿಸುತ್ತಾನೆ. ಮುಂದಿನ\nನಾಲ್ಕು ಶ್ಲೋಕದಲ್ಲಿ ಅರ್ಜುನ ಭಗವಂತನ ಅನಂತ ಶಕ್ತಿಯ ಪಾರಮ್ಯದ ಅನುಸಂಧಾನವನ್ನು\nವ್ಯಕ್ತಪಡಿಸುವುದನ್ನು ಕಾಣುತ್ತೇವೆ.",
  "10.12": "ಅರ್ಜುನ ಉವಾಚ --\nಪರಂ ಬ್ರಹ್ಮ ಪರಂ ಧಾಮ ಪವಿತ್ರಂ ಪರಮಂ ಭವಾನ್ ।\nಪುರುಷಂ ಶಾಶ್ವತಂ ದಿವ್ಯಮಾದಿದೇವಮಜಂ ವಿಭುಮ್ ॥\n\n'ನೀನು ಪರಂಬ್ರಹ್ಮ, ಪರಮಧಾಮ ಮತ್ತು ಪರಮ ಪವಿತ್ರನು. ನೀನೇ ಶಾಶ್ವತ, ದಿವ್ಯ ಪುರುಷ, ಆದಿದೇವ, ಹುಟ್ಟಿಲ್ಲದವನು ಮತ್ತು ಸರ್ವವ್ಯಾಪಿಯಾಗಿದ್ದೀಯೆ.'\n\nಭಗವಂತನ ವಿಭೂತಿಗಳನ್ನು ಕೇಳಿದ ನಂತರ ಅರ್ಜುನನ ಉದ್ಗಾರ. 'ಪರಂ ಬ್ರಹ್ಮ' — ಪರಮ ಸತ್ಯ. 'ಆದಿದೇವ' — ದೇವತೆಗಳ ದೇವ. 'ಅಜ' — ಹುಟ್ಟಿಲ್ಲದವ. 'ವಿಭು' — ಸರ್ವವ್ಯಾಪಿ. ಮಧ್ವ ಮತದ ಪ್ರಕಾರ 'ಪರಂಬ್ರಹ್ಮ' = ನಾರಾಯಣ.",
  "10.13": "ಆಹುಃ ತ್ವಾಮ್‌ ಋಷಯಃ ಸರ್ವೇ ದೇವ ಋಷಿಃ ನಾರದಃ ತಥಾ ।\n\nಅಸಿತಃ ದೇವಲಃ ವ್ಯಾಸಃ ಸ್ವಯಂ ಚ ಏವ ಬ್ರವೀಷಿ ಮೇ -- ಪೂಜ್ಯನಾದ ನೀನು ಹಿರಿದಕ್ಕಿಂತ ಹಿರಿಯ ತತ್ವ.\n\nಹಿರಿಯ ಆಸರೆ. ಪಾವನಗಳಿಗೂ ಪಾವನ. ನಿನ್ನನ್ನು. ಗುಣಪೂರ್ಣನಾದ, ಪರಮಪುರುಷನೆಂದು,\nಬದಲಾಗದವನೆಂದು, ಲೀಲಾಮಯನೆಂದು, ಎಲ್ಲಾ ದೇವತೆಗಳಿಗೂ ಮೊದಲಿಗನೆಂದು, ಜನ್ಮರಹಿತನೆಂದು,\nಬಗೆಬಗೆಯ ರೂಪಗಳಿಂದ ಎಲ್ದೆಡೆ ತುಂಬಿರುವವನೆಂದು ಬಲ್ಲವರೆಲ್ಲ ಹೊಗಳುತ್ತಾರೆ. ದೇವರ್ಷಿ ನಾರದ ಕೂಡಾ.\nಅಸಿತ-ದೇವಲರು ಕೂಡಾ. ವ್ಯಾಸ ಮುನಿ ಹೇಳಿದ್ದುಂಟು. ಸ್ವತಃ ನೀನೂ ನನಗೆ ಹೇಳುತ್ತಿದ್ದೀಯಾ.\n\nಇಲ್ಲಿ ಅರ್ಜುನ ಕೃಷ್ಣನನ್ನು “ಪರಂಬ್ರಹ್ಮ, ಪರಂಧಾಮ, ಪರಮಪವಿತ್ರ ನೀನು” ಎಂದು ಸಂಬೋಧಿಸುತ್ತಾನೆ.\nಯಾವುದು ಎಲ್ಲವುದಕ್ಕೆಂತ ದೊಡ್ಡದೋ ಅದು ಬ್ರಹ್ಮ. ಬ್ರಹ್ಮ ಅನ್ನು ವ ಪದವನ್ನು ಇನ್ನೂ ಅನೇಕ ಅರ್ಥದಲ್ಲಿ\nಬಳಸುತ್ತಾರೆ. ಅದಕ್ಕಾಗಿ ಇಲ್ಲಿ ಸ್ಪಷ್ಟತೆಗಾಗಿ 'ಪರಂಬ್ರಹ್ಮ' ಎಂದಿದ್ದಾರೆ. “ಎಲ್ಲಕ್ಕಿಂತ ದೊಡ್ಡವ ಮತ್ತು\nನಂಬಿದವರನ್ನು ಎತ್ತರಕ್ಕೇರಿಸುವ ನೀನು ಪರಿಪೂರ್ಣ. ನಾನು ನನ್ನ ವ್ಯಕ್ತಿತ್ವದ ಪೂರ್ಣತೆಯನ್ನು ಕಾಣಲು ನಿನ್ನ\nಅನುಗ್ರಹ ಬೇಕು” ಎನ್ನುವ ಧ್ವನಿ ಈ ಸಂಬೋಧನೆಯಲ್ಲಿದೆ. ಇನ್ನು ಪರಂ ಧಾಮ: 'ಧಾಮ' ಅಂದರೆ ಆಶ್ರಯ.\nಭಗವಂತನನ್ನು ಆಶ್ರಯಿಸದೇ ಇರುವ ಒಂದು ವಸ್ತು ಈ ಜಗತ್ತಿನಲ್ಲಿಲ್ಲ. “ನೀನು ಸರ್ವಸ್ವತಂತ್ರ, ಮತ್ತು\nನಾವೆಲ್ಲರೂ ನಿನ್ನ ಅಧೀನ, ನೀನು ಆಶ್ರಯಧಾತ ಮತ್ತು ನಾವು ಆಶ್ರಿತರು” ಎನ್ನು ವ ಅರ್ಥದಲ್ಲಿ ಅರ್ಜುನ\nಕೃಷ್ಣನನ್ನು 'ಪರಂಧಾಮ' ಎಂದಿದ್ದಾನೆ. ತತ್ತ್ವಾಭಿಮಾನಿ ದೇವತೆಗಳು ಒಂದೊಂದು ರೂಪದಲ್ಲಿ ನಮಗೆ ಆಶ್ರಯ\nನೀಡುತ್ತಾರೆ. ಆದರೆ ಇಂತಹ ದೇವತೆಗಳಿಗೂ ಆಶ್ರಯಧಾತನಾಗಿರುವ ಭಗವಂತ ಪರಂಧಾಮ. ಸಮಸ್ತ ಜೀವರ\nಅನಂತ ಯಾತ್ರೆಯಲ್ಲಿ ಆಶ್ರಯಧಾತನಾಗಿ ಉದ್ಧಾರ ಮಾಡುವ ಭಗವಂತ ಸರ್ವಾಶ್ರಯಧಾತ.\n\nಭಗವಂತ 'ಪರಮಪವಿತ್ರ'. ಇಂತಹ ಭಗವಂತನನ್ನು ನಾವು ಪವಿತ್ರತೆಯ ಪ್ರತೀಕವಾದ ಅಗ್ನಿ ಮುಖೇನ\nಉಪಾಸನೆ ಮಾಡುತ್ತೇವೆ. ಅಗ್ನಿ ಸ್ವಯಂ ಪವಿತ್ರ ಮತ್ತು ಅದು ಎಂದೂ ಕೊಳಕಾಗುವುದಿಲ್ಲ. ಅಗ್ನಿ ತನ್ನ ಸ್ಪರ್ಶಕ್ಕೆ\nಬಂದ ವಸ್ತುವನ್ನು ಕೊಳೆರಹಿತ ಮಾಡುತ್ತದೆ. ಭಗವಂತ ನಮ್ಮನ್ನು ಮತ್ತು ಪ್ರಪಂಚವನ್ನು ಪಾವನಗೊಳಿಸುವ\nಪರಮಶಕ್ತಿ.\n\nಅರ್ಜುನ ಇಲ್ಲಿ ತನ್ನೆಲ್ಲಾ ಭೌತಿಕ ಸಂಬಂಧವನ್ನು ಮೀರಿ ತನ್ನೆದುರು ನಿಂತಿರುವ ಆ ಪರಬ್ರಹ್ಮನನ್ನು\nಕಾಣುತ್ತಿದ್ದಾನೆ. “ನನ್ನಲ್ಲಿ ಕೊಳೆ ತುಂಬಿದೆ, ಅಸೂಯೆ ಅಸಹನೆ ತುಂಬಿದೆ. ನಿನ್ನ ಅನುಗ್ರಹದಿಂದ, ಆಶ್ರಯದಿಂದ\nನಾನು ಪವಿತ್ರನಾಗಬೇಕು. ನಿನ್ನಿಂದ ನಾನು ಆ ಎತ್ತರಕ್ಕೇರಿ ನನ್ನ ಪೂರ್ಣತೆಯನ್ನು ಪಡೆಯಬೇಕು” ಎನ್ನುವ\nಬಯಕೆ ಅರ್ಜುನನ ಈ ಸಂಬೋಧನೆಯಲ್ಲಿದೆ.\n\nಕೆಲವೊಮ್ಮೆ ನಾವು ಉದ್ವೇಗದಿಂದ ಅತಿಶಯವಾಗಿ ಮಾತನಾಡುತ್ತೇವೆ. ಇಲ್ಲಿ ಅರ್ಜುನ ತಾನು ಉದ್ವೇಗದಿಂದ\nಮಾತನಾಡುತ್ತಿಲ್ಲ ಎನ್ನು ವುದನ್ನು ಖಚಿತಪಡಿಸಿಕೊಳ್ಳುತ್ತಾನೆ. ಒಬ್ಬ ಸಾಧಕನಿಗೆ ದೇವರ ಉಪಾಸನೆಯಲ್ಲಿ ಇದು\nಬಹಳ ಮುಖ್ಯ ಅಂಶ. ಏಕೆಂದರೆ ನಾವು ದೇವರ ಬಗ್ಗೆ ಏನು ಕಲ್ಪನೆ ಮಾಡಿದರೂ ಅದು ಕೇವಲ ಕಲ್ಪನೆ ಹೊರತು\nಸಾಕ್ಷಾತ್ಕಾರವಲ್ಲ. ನಮ್ಮ ಕಲ್ಪನೆ ನಮ್ಮ ಮನಸ್ಸಿನ ಸ್ಥಿತಿಯನ್ನು ಹೊಂದಿಕೊಂಡಿರುತ್ತದೆ. ಮನಸ್ಸಿನಲ್ಲಿ ಉತ್ಸಾಹ\nಇದ್ದಾಗ ಏನೇನೋ ಹೊಸ-ಹೊಸ ಕಲ್ಪನೆಗಳು ಬರುತ್ತವೆ. ಅವೆಲ್ಲವೂ ಸತ್ಯವಾಗಿರಬೇಕೆಂದಿಲ್ಲ. ಹಾಗಾಗಿ\nಅವರವರ ಬುದ್ಧಿ ಮಟ್ಟಕ್ಕೆ ತಕ್ಕಂತೆ ಅವರವರ ಕಲ್ಪನೆಯೇ ಹೊರತು ಭಗವಂತ ಹೇಗಿದ್ದಾನೋ ಹಾಗೇ ನಮ್ಮ\nಕಲ್ಪನೆ ಇರುವುದಿಲ್ಲ. ಈ ಕಾರಣದಿಂದ ಇಲ್ಲಿ ಅರ್ಜುನ ತನಗೆ ಬಂದ ವಿಚಾರ ತನ್ನ ಬುದ್ಧಿಮಟ್ಟದ ಕಲ್ಪನೆಯಲ್ಲ\n\nಇದು ವಸ್ತುಸ್ಥಿತಿ ಎನ್ನುವುದನ್ನು ಖಚಿತಪಡಿಸಿಕೊಳ್ಳುತ್ತಾನೆ. ಆತ ಖುಷಿಗಳು, ದೇವರ್ಷಿನಾರದರು ಹೇಳಿರುವ\nಮಾತನ್ನು ಇಲ್ಲಿ ನೆನಪಿಸಿಕೊಳ್ಳುತ್ತಾನೆ.\n\nಅರ್ಜುನ ಹೇಳುತ್ತಾನೆ “ನಿನ್ನನ್ನು ಪುರುಷಃ, ಶಾಶ್ವತಃ, ದಿವ್ಯಃ, ಆದಿದೇವಃ ಅಜಃ , ವಿಭುಃ ಎಂದು ಈ ಮಹಾತ್ಮರು\nಹೇಳಿದ್ದಾರೆ” ಎಂದು. ಇಲ್ಲಿ ಬಳಸಿರುವ ಒಂದೊಂದು ಪದದಲ್ಲಿ ಭಗವಂತನ ಅನಂತ ಗುಣ ಅಡಗಿದೆ.\nವಿಷ್ಣುಸಹಸ್ರನಾಮದಲ್ಲಿ ಈ ಎಲ್ಲಾ ಪದಗಳನ್ನು ಭಗವಂತನ ನಾಮವಾಗಿ ನಾವು ಕಾಣುತ್ತೇವೆ. ಬನ್ನಿ, ಇಲ್ಲಿ\nಸಂಕ್ಷಿಪ್ತವಾಗಿ ಈ ಪದಗಳ ಅರ್ಥಾನುಸಂಧಾನ ಮಾಡೋಣ:\n\nಪುರುಷಃ : ಇಲ್ಲಿ ಪುರುಷ ಎಂದರೆ ಗಂಡಸು ಎನ್ನುವ ಅರ್ಥವಲ್ಲ. ಪುರದಲ್ಲಿ ವಾಸಿಸುವವನು 'ಪುರುಷಃ'. ಸಮಸ್ತ\nವೇದಗಳ ಸಾರಭೂತವಾದ ಸೂಕ್ತಗಳ ರಾಜ 'ಪುರುಷಸೂಕ್ತ' ಭಗವಂತನನ್ನು “ಸಹಸ್ರ ಶೀರ್ಷಾ ಪುರುಷಃ' ಎಂದು\nಕರೆದಿದೆ. ಸೃಷ್ಟಿ ಕಾಲದಲ್ಲಿ ಏನೂ ಇಲ್ಲದಾಗಲೂ ಇದ್ದು, ಈ ಸೃಷ್ಟಿಯನ್ನು ನಿರ್ಮಾಣ ಮಾಡಿದ ಭಗವಂತ\nಪುರುಷಃ. ಪ್ರಳಯ ಕಾಲದಲ್ಲಿ ಎಲ್ಲವನ್ನೂ ಸುಟ್ಟ ಭಗವಂತ ಪುರ-ಉಷ. ಪ್ರಪಂಚದಲ್ಲಿ ಅನಂತವಾಗಿ, ಅನಂತ\nಕಾಲ, ಅನಂತ ಸಾಮರ್ಥ್ಯ, ಅನಂತ ಗುಣಗಳಿಂದ ತುಂಬಿರುವ ಭಗವಂತ ಪುರ-ಸಹ. ಪ್ರಳಯ ಕಾಲದಲ್ಲಿ ಏನೂ\nಇಲ್ಲದಾಗ ಇದ್ದು, ಸೃಷ್ಟಿ ಕಾಲದಲ್ಲಿ ತನ್ನ ನಾಭಿಯಿಂದ ಒಂದೊಂದನ್ನು ಸೃಷ್ಟಿ ಮಾಡಿದ ಭಗವಂತ, ಮೊದಲು\n\"ಮಹತತ್ವವನ್ನು” ಸೃಷ್ಟಿ ಮಾಡಿದ. ಮಹತತ್ವ ಎಂದರೆ ಇಡೀ ಪ್ರಪಂಚದ ಭೂತಪ್ರಜ್ಞೆ ಜಾಗೃತಿ. ಹಿಂದೆ ಇದ್ದ\nಸಮಸ್ತ ಸೃಷ್ಟಿಯ ಸ್ಮರಣೆಯನ್ನು ಚಿತ್ತಾಭಿಮಾನಿ ಬ್ರಹ್ಮ-ವಾಯುವಿಗೆ ಕೊಟ್ಟು, ಸೂಕ್ಷ್ಮ ರೂಪದ ಪ್ರಪಂಚ\nನಿರ್ಮಾಣ. ನಂತರ ದೇವತೆಗಳು, ಪಂಚಭೂತಗಳ ನಿರ್ಮಾಣ. ಹೀಗೆ ನಿರ್ಮಾಣವಾದ ಸ್ಥೂಲ\nಬ್ರಹ್ಮಾಂಡದೊಳಗೆ ಭಗವಂತ ತುಂಬಿಕೊಂಡ. ಒಂದೊಂದು ಪಿಂಡಾಂಡದೊಳಗೆ ಒಂದೊಂದು ರೂಪದಲ್ಲಿ ಬಿಂಬ\nರೂಪನಾಗಿ ತುಂಬಿ ಆ ಪಿಂಡಾಂಡದಿಂದ ಮಾಡಿಸಬೇಕಾದ ಕಾರ್ಯವನ್ನು ಮಾಡಿಸಿ, ಮೋಕ್ಷವನ್ನು ಕರುಣಿಸುವ\nಭಗವಂತ ಪುರುಷಃ. ಹೀಗೆ ಸೃಷ್ಟಿಯ ಮೊದಲು, ಸೃಷ್ಟಿಯ ಕಾಲದಲ್ಲಿ, ಸೃಷ್ಟಿಯಾದ ವಸ್ತುವಿನೊಳಗೆ, ಸೃಷ್ಟಿಯ\nಸಾಧನೆಯಲ್ಲಿ, ಸಾಧನೆಯಿಂದ ಮುಕ್ತಿಯ ತನಕ ಎಲ್ಲೆಡೆ ಇರುವ ಈ ಹೃತ್ಕಮಲ ಮಧ್ಯ ನಿವಾಸಿ ಭಗವಂತ,\nಪೂರ್ಣವಾದ ಷಡ್ಲುಣಗಳಿಂದ ತುಂಬಿರುವ ಜ್ಞಾನಾನಂದ ಸ್ವರೂಪ. ಪು-ರು-ಷಃ-ಪುರುಷ;; ಇಲ್ಲಿ 'ಪು' ಎಂದರೆ\nನಮ್ಮನ್ನು ಪಾವನಗೊಳಿಸುವ ಪರಮಪವಿತ್ರ. 'ರು' ಎಂದರೆ 'ರುವಂತಿ', ಪ್ರಪಂಚದ ಎಲ್ಲಾ ಶಬ್ದಗಳಿಂದ\nವಾಚ್ಯನಾದವನು. 'ಷಃ' ಅಥವಾ 'ಸಹ' ಎಂದರೆ ಎಲ್ಲಾ ವಸ್ತುಗಳೊಳಗೆ ತುಂಬಿರುವ ಸರ್ವಾಂತರ್ಯಾಮಿ ತತ್ವ.\nಹೀಗೆ ಪುರುಷಃ ಎನ್ನುವ ಭಗವಂತನ ನಾಮ ಅನೇಕ ರೀತಿಯಲ್ಲಿ ಭಗವಂತನ ಗುಹಾನುಸಂಧಾನ ಮಾಡುವ\nನಾಮ.\n\nಶಾಶ್ವತಃ: ಅನಾದಿ ಅನಂತ ಕಾಲದಲ್ಲಿ ಯಾವುದೇ ಬದಲಾವಣೆಗೆ ಒಳಪಡದೆ, ಎಂದೆಂದೂ ಶಾಶ್ವತವಾಗಿರುವ\nಆನಂದಸ್ವರೂಪ ಭಗವಂತ ಶಾಶ್ವತಃ.\n\nದಿವ್ಯಃ : ದಿವ್ಯ ಪದಕ್ಕೆ ಅನೇಕ ಅರ್ಥಗಳಿವೆ. ಮೂಲವಾಗಿ ದಿವ್ಯ ಅಥವಾ 'ದೇವರು' ಈ ಪದಗಳು 'ದಿವು' ಎನ್ನುವ\nಧಾತುವಿನಿಂದ ಬಂದಿರುವುದು. ಪ್ರಾಚೀನ ಧಾತು ಪಾಠದಲ್ಲಿ ಈ ಧಾತುವಿಗೆ ಏಳು ಅರ್ಥವನ್ನು ನೋಡಬಹುದು;\nಅವುಗಳೆಂದರೆ: ೧) ಧ್ಯುತಿ ೨) ವಿಜಿಗೀಶ ೩) ಕಾಂತಿ ೪) ಸ್ತುತಿ ೫) ವ್ಯವಹಾರ ೬) ಕ್ರೀಡಾ ೭) ಗತಿಶು.\n\n೧) ಧ್ಯುತಿ : ಧ್ಯುತಿ ಅಂದರೆ ಬೆಳಕಿನ ಸ್ವರೂಪ. ಬೆಳಕಿನ ಪುಂಜವಾದ ಸೂರ್ಯ ಚಂದ್ರಾದಿಗಳಿಗೆ ಬೆಳಕನ್ನೀಯುವ\nಭಗವಂತ ನಮ್ಮೊಳಗೆ ಜ್ಞಾನದ ಬೆಳಕನ್ನು ತುಂಬುತ್ತಾನೆ.\n\n೨) ವಿಜಿಗೀಶ: ಭಗವಂತ ಎಲ್ಲರಿಗಿಂತ ಎತ್ತರದಲ್ಲಿರುವವನು ಹಾಗೂ ಗೆಲುವಿನ ಸ್ವರೂಪ.\n\n೩) ಕಾಂತಿ: ಕೇವಲ ಇಚ್ಚೆಯಿಂದ ಸೃಷ್ಟಿ ಮಾಡಬಲ್ಲವ. ನಮಗೆ ಇಚ್ಚೆ ಯನ್ನು ಕೊಟ್ಟವ ಹಾಗೂ ಅದನ್ನು ಅವರವರ\nಯೋಗ್ಯತೆಗೆ ತಕ್ಕಂತೆ ಪೂರೈಸುವವ.\n\n೪) ಸ್ತುತಿ: ಎಲ್ಲರಿಂದ ಸ್ತುತನಾದವನು; ಎಲ್ಲರೂ ಯಾರನ್ನು ಸ್ತುತಿಸುತ್ತಾರೋ ಅವನು ಸರ್ವಶಬ್ದ ವಾಚ್ಯನಾದ\nಭಗವಂತ.\n\n೫) ವ್ಯವಹಾರ: ಜಗತ್ತಿನ ಸಮಸ್ತ ವ್ಯವಹಾರವನ್ನು ನಿರ್ವಹಿಸುವವ.\n\n೬) ಕ್ರೀಡಾ: ಸೃಷ್ಟಿ-ಸ್ಥಿತಿ-ಸಂಹಾರ ಇದು ಭಗವಂತನಿಗೊಂದು ಕ್ರೀಡೆ.\n\n೭) ಗತಿಶು: ಚಲನೆ ಮತ್ತು ಜ್ಞಾನ ಕೊಟ್ಟ ವ. ಯಾರು ಎಲ್ಲಾ ಕಡೆ ಗತನಾಗಿದ್ದಾನೋ; ಎಲ್ಲವನ್ನೂ ತಿಳಿದಿದ್ದಾನೋ;\nಎಲ್ಲರೊಳಗೆ ಬಿಂಬ ರೂಪದಲ್ಲಿ ನೆಲೆಸಿದ್ದಾನೋ ಅವನು ದಿವ್ಯ ಅಥವಾ 'ದೇವ'.\n\nಆದಿದೇವಃ: ಈ ಜಗತ್ತಿನ ಸೃಷ್ಟಿ-ಸ್ಥಿತಿ-ಸಂಹಾರ ಯಾರಿಗೆ ಲೀಲಾ ಮಾತ್ರವೋ ಆತ ಆದಿದೇವಃ. ಭಗವಂತ ಈ\nಪ್ರಪಂಚ ಇರುವಾಗಲೂ, ಇಲ್ಲದಿರುವಾಗಲೂ ಇರುವವ. ಆತ ಎಲ್ಲಕ್ಕಿಂತ ಎತ್ತರದಲ್ಲಿರುವವನು. ಎಲ್ಲಾ\nಕಾಲದಲ್ಲೂ ಜಗತ್ತಿನ ಸರ್ವ ವ್ಯವಹಾರವನ್ನು ನಡೆಸುವವ ಆತ. ಹೀಗೆ ಎಲ್ಲವುದರ ಒಳಗಿದ್ದು, ಎಲ್ಲಾ\nಕ್ರಿಯೆಗಳನ್ನು ನಡೆಸುವ ಭಗವಂತ ಆದಿದೇವಃ.\n\nಅಜಃ: 'ನ ಜಾಯತೇ ಇತಿ ಅಜಃ; 'ಜ' ಎಂದರೆ ಜನನ; ಅ-ಜಃ-ಅಜಃ ಎಂದರೆ ಹುಟ್ಟಿರದವನು. ಹುಟ್ಟದವನ\nಹೊಕ್ಕುಳಲ್ಲಿ ಹುಟ್ಟಿದ ಚತುರ್ಮುಖನನ್ನು ಅಜ ಎನ್ನುತ್ತಾರೆ. ಇಂತಹ ಚತುರ್ಮುಖನೊಳಗೆ ಸನ್ನಿಹಿತನಾಗಿ, ಸೃಷ್ಟಿ\nಮಾಡುವ ಭಗವಂತ, ತಾನು ಹುಟ್ಟದೆ, ಎಲ್ಲವನ್ನೂ ಸೃಷ್ಟಿ ಮಾಡಿ ಸಂಹಾರ ಮಾಡುವ ಅಜಃ. ಎಲ್ಲರೂ\nಭಗವಂತನ ಮಕ್ಕಳು, ಆದರೆ ಆತ ಯಾರಿಗೂ ಹುಟ್ಟಿದವನಲ್ಲ. ಏಕೆಂದರೆ ಅವನಿಗೆ ಹುಟ್ಟು-ಸಾವು ಎಂಬುದಿಲ್ಲ.\nಇನ್ನು ಅಜಃ ಎಂದರೆ ಎಲ್ಲಾ ಕಡೆ ವ್ಯಾಪಿಸಿರುವವನು ಕೂಡಾ ಹೌದು. ಅ-ಜ-ಅಜಃ. ಇಲ್ಲಿ 'ಅ' ಎಂದರೆ 'ಅಲ್ಲ'\nಅಥವಾ ಇಲ್ಲ! ಅಂದರೆ ಅವನು ನಾವು ತಿಳಿದ ಯಾವ ವಸ್ತುವೂ ಅಲ್ಲ. ಅವನಲ್ಲಿ ಯಾವ ದೋಷವೂ ಇಲ್ಲ.\nಇನ್ನೊಂದು ಅರ್ಥದಲ್ಲಿ ಅಜಃ ಅಂದರೆ ಯಾರಿಂದಲೂ ಹುಟ್ಟದವನು-ಆದರೆ ಎಲ್ಲರಲ್ಲೂ ಹುಟ್ಟುವವನು!\nತದ್ವಿರುದ್ದವಾದ ಅರ್ಥ ಎನ್ನುತೀರಾ? ಹೌದು, ಭಗವಂತ ಯಾರಿಂದಲೋ ಹುಟ್ಟಿ ಬರುವ ವಸ್ತುವಲ್ಲ. ಆದರೆ ಬಿಂಬ\nರೂಪನಾಗಿ ಪ್ರತಿಯೊಂದು ಗರ್ಭದಲ್ಲಿ ನೆಲೆಸಿ ಏಕ ಕಾಲದಲ್ಲಿ ಅನೇಕ ರೂಪಿಯಾಗಿ ಆತ ಹುಟ್ಟುತ್ತಾನೆ.\nಗರ್ಭಿಣಿಯ ಗರ್ಭದಲ್ಲಿ ಭಗವಂತ ಬಿಂಬರೂಪನಾಗಿ ನೆಲೆಸಿ ಜನಿಸುತ್ತಾನೆ.\n\nವಿಭುಃ: ವಿವಿಧ-ಭವತಿ- ಅಂದರೆ ವಿವಿಧ ರೂಪ ತೊಟ್ಟ ಅನಂತರೂಪಿ. ಸರ್ವಸಮರ್ಥನಾಗಿ ಪ್ರಪಂಚದಲ್ಲೆಲ್ಲಾ\nತುಂಬಿರುವ ಭಗವಂತ ವಿಭುಃ.\n\nಇಲ್ಲಿ ಅರ್ಜುನ ವಿಶೇಷವಾಗಿ ದೇವರ್ಷಿ ನಾರದ, ಅಸಿತ-ದೇವಲ ಮತ್ತು ವ್ಯಾಸರ ಹೆಸರನ್ನು ಉಲ್ಲೇಖಿಸುತ್ತಾನೆ.\nಏಕೆಂದರೆ ಅರ್ಜುನ ಇವರನ್ನು ಕಂಡಿದ್ದ ಮತ್ತು ಅವರು ಭಗವಂತನ ಬಗೆಗೆ ಹೇಳುವುದನ್ನು ಕೇಳಿದ್ದ. ನಾರದ\nಮಹಾನ್‌ ಜ್ಞಾನಿ ಎನ್ನುವುದು ನಮಗೆ ತಿಳಿದಿದೆ. ದೇವತಾ ತಾರತಮ್ಯದಲ್ಲಿ ಇವರು ಹದಿನಾಲ್ಕನೇ\nಮೆಟ್ಟಿಲಲ್ಲಿದ್ದಾರೆ. ಇವರು ಧರ್ಮರಾಯನ ಆಸ್ಥಾನದಲ್ಲಿ ಭಗವಂತನ ಅಗ್ರಪೂಜೆ ನಡೆದಾಗ ಬಂದು ಹರಸಿರುವ\nದೇವಲೋಕದ ಋಷಿ. ನರ ಸಮುದಾಯದಲ್ಲಿರುವ ಅಜ್ಞಾನವನ್ನು ಸಂಹಾರ ಮಾಡಿ, ಭಗವಂತನ ಜ್ಞಾನವನ್ನು\nಕೊಡುವ ನಾರದ, ನಮಗೆ ಸತ್ಯವನ್ನು ಹೊಳೆಸುವ ಅಂತಃಪ್ರಜ್ಞೆಯ(intuition)ದೇವತೆ. ಆಜ್ಞಾಚಕ್ರವನ್ನು\n\nಜಾಗೃತಗೊಳಿಸಿದಾಗ ನಮಗೆ ನಾರದರ ದರ್ಶನವಾಗುತ್ತದೆ. ಯಾವುದನ್ನು ಮಾಡಬೇಕು, ಯಾವುದನ್ನು\nಮಾಡಬಾರದು ಎನ್ನುವುದನ್ನು ಅಂತರ್ದೃಷ್ಟಿಯಿಂದ ಉತ್ತರಿಸುವವರು ನಾರದರು. ಅಸಿತ-ದೇವಲರು\nಮಂತ್ರದೃಷ್ಟಾರರಾದ ವೇದಕಾಲದ ಖುಷಿಗಳು. ಇವರು ಧರ್ಮರಾಯನ ಸಭೆಗೆ ಬಂದು ಆತನಿಗೆ\nಧರ್ಮೋಪದೇಶ ಮಾಡಿದ್ದನ್ನು ಅರ್ಜುನ ನೋಡಿದ್ದ. ಇನ್ನು ವ್ಯಾಸರು: ವೇದವನ್ನು ವಿಭಾಗ ಮಾಡಿ, ನಮಗೆ\nಹದಿನೆಂಟು ಪುರಾಣವನ್ನು , ಮಹಾಭಾರತ, ಪಂಚಮವೇದವನ್ನು ಕೊಟ್ಟ ಭಗವಂತನ ಅವತಾರ. “ಈ ಎಲ್ಲಾ\nಮಹಾತ್ಮರು ಏನನ್ನು ಹೇಳಿದ್ದರೋ, ಅದನ್ನೇ ನೀನು ನನಗೆ ಹೇಳುತ್ತಿದ್ದೀಯ” ಎನ್ನುತ್ತಾನೆ ಅರ್ಜುನ. ಹೀಗೆ\nತನಗಾಗುತ್ತಿರುವ ಅನುಭವ ಕೇವಲ ಭ್ರಮೆ ಅಲ್ಲ ಎನ್ನುವುದನ್ನು ಅರ್ಜುನ ಖಚಿತಪಡಿಸಿಕೊಳ್ಳುತ್ತಾನೆ.",
  "10.14": "ಸರ್ವಮ್‌ ಏತತ್‌ ಋತಮ್‌ ಮನ್ಯೇ ಯತ್‌ ಮಾಮ್‌ ವದಸಿ ಕೇಶವ |\n\nನಹಿತೇ ಭಗವನ್‌ ವ್ಯಕ್ತಿಮ್‌ ವಿದುಃ ದೇವಾಃ ನ ದಾನವಾಃ -ಓ ಕೇಶವಾ, ನೀನು ನನಗೇನು ಹೇಳಿದೆಯೋ\nಅದೆಲ್ಲವೂ ನಿಜವೆಂದು ಬಲ್ದೆ. ಓ ಭಗವಾನ್‌, ನೀನು ಮೂಡಿಬಂದ ಬಗೆಯನ್ನು ದೇವತೆಗಳಾಗಲೀ,\nದಾನವರಾಗಲೀ ಅರಿತವರಲ್ಲ.\n\n“ನೀನು ಹೇಳುತ್ತಿರುವುದರಲ್ಲಿ ಯಾವುದೇ ಅತಿಶಯೋಕ್ತಿ ಇಲ್ಲ ಎನ್ನುವುದನ್ನು ಬಲ್ಲೆ. ನಿನ್ನ ಅರಿವಿನ\nಅಭಿವ್ಯಕ್ತಿಯನ್ನು ದೇವತೆಗಳಾಗಲೀ ದಾನವರಾಗಲೀ ತಿಳಿದಿಲ್ಲ” ಎನ್ನುತ್ತಾನೆ. ಅರ್ಜುನ. ದೇವತೆಗಳಿಗೆ\nಭಗವಂತನ ಗುಣಪ್ರಮಾಣವನ್ನು ಅಳೆಯಲು ಸಾಧ್ಯವಾಗಿಲ್ಲ... ದಾನವರು ಭಗವಂತನಲ್ಲಿ ದೋಷ\nಹುಡುಕುವುದರಲ್ಲಿ ಯಶಸ್ವಿ ಆಗಿಲ್ಲ. ಏಕೆಂದರೆ ಭಗವಂತ ಅನಂತ ಗುಣಪೂರ್ಣ. ಆತನಲ್ಲಿ ಯಾವುದೇ\nದೋಷವಿಲ್ಲ. ಆತನನ್ನು ಪೂರ್ಣ ಅರ್ಥಮಾಡಿಕೊಳ್ಳುವುದು ಅಸಾಧ್ಯ. ಭಗವಂತನ ಬಗೆಗೆ ಅವನು ಹೇಳಬೇಕೇ\nಹೊರತು ಇನ್ನೊಬ್ಬರು ಅದನ್ನು ವರ್ಣಿಸಲು ಸಾಧ್ಯವಿಲ್ಲ. ಭಗವಂತನನ್ನು ಪೂರ್ಣ ತಿಳಿಯುವುದು ಹಾಗಿರಲಿ,\nಆತನ ಒಂದು ಅವತಾರವನ್ನಾಗಲೀ, ಅವತಾರದಲ್ಲಿನ ಆತನ ಒಂದು ಲೀಲೆಯನ್ನು ಪೂರ್ಣ\nಅರ್ಥಮಾಡಿಕೊಳ್ಳುವುದು ಕಷ್ಟ. ಕೃಷ್ಣ ತನ್ನ ಅವತಾರದಲ್ಲಿ ನಡೆದುಕೊಂಡ ರೀತಿ ನಮಗೆ ಅರ್ಥವಾಗುವುದಿಲ್ಲ.\nನಮಗೆ ಅದು ವಿಚಿತ್ರ ಎನಿಸುತ್ತದೆ. ಆತನನ್ನು ಅರಿಯುವುದು ಅಷ್ಟು ಸುಲಭದ ಕೆಲಸವಲ್ಲ. ಆತನ ಒಂದೊಂದು\nನಡೆಯ ಹಿಂದೆಯೂ ಒಂದೊಂದು ಸಂದೇಶವಿದೆ.",
  "10.15": "ಸ್ವಯಮ್‌ ಏವ ಆತ್ಮನಾ ಆತ್ಮಾನಮ್‌ ವೇತ್ಛ ತ್ವಮ್‌ ಪುರುಷೋತ್ತಮ |\nಭೂತಭಾವನ ಭೂತೇಶ ದೇವದೇವ ಜಗತ್‌ ಪತೇ ॥",
  "10.16": "ವಕ್ತುಮ್‌ ಅರ್ಹಸಿ ಅಶೇಷೇಣ ದಿವ್ಯಾಃ ಹಿ ಆತ್ಮ ವಿಭೂತಯಃ |\nಯಾಭಿಃ ವಿಭೂತಿಭಿಃ ಲೋಕಾನ್‌ ಇಮಾನ್‌ ತ್ವಮ್‌ ವ್ಯಾಪ್ಯ ತಿಷ್ಠಸಿ -ಓ ಪುರುಷೋತ್ತಮಾ, ನೀನೇ ಸ್ವತಃ\nನಿನ್ನಳವಿನಿಂದ ನಿನ್ನನ್ನು ಅರಿತಿರುವೆ. ಓ ಎಲ್ಲಾ ಜೀವಿಗಳ ಸೃಷ್ಟಾರನೇ, ಎಲ್ಲಾ ಜೀವಿಗಳ ದೊರೆಯೇ,\nದೇವತೆಗಳಿಗೂ ಹಿರಿಯ ದೈವತವೇ, ಜಗದೊಡೆಯನೇ, ಯಾವ ರೂಪಗಳಿಂದ ನೀನು ಈ ಲೋಕಗಳನ್ನೆಲ್ಲಾ\nತುಂಬಿ ನಿಂತಿರುವೆಯೋ ಅಂತಹ ಅಲೌಕಿಕವಾದ ನಿನ್ನ ಬಗೆಬಗೆಯ ರೂಪಗಳ ಹಿರಿಮೆಗಳನ್ನು ಬಿಡದೆ\nತಿಳಿಹೇಳಬೇಕು ನೀನೇ.\n\nಅರ್ಜುನ ಹೇಳುತ್ತಾನೆ: “ನಿನ್ನ ಗುಣಪ್ರಮಾಣವನ್ನು ದೇವತೆಗಳಿಂದಲೂ ಅಳೆಯಲು ಸಾಧ್ಯವಿಲ್ಲ. ಆದ್ದರಿಂದ ನಿನ್ನ\nಬಗೆಗೆ ತಿಳಿದಿರುವುದು ನೀನೊಬ್ಬನೇ. ಅದನ್ನು ನೀನು ನೀನಾಗಿಯೇ ಹೇಳಬೇಕು ಹೊರತು, ಇನ್ನೊ ಬ್ಬರಿಂದ\nಹೇಳಲು ಸಾಧ್ಯವಿಲ್ಲ. ಏಕೆಂದರೆ ನೀನು ಪುರುಷೋತ್ತಮ” ಎಂದು. ಇಲ್ಲಿ ಪುರುಷೋತ್ತಮ ಎನ್ನುವ ವಿಶೇಷಣ\nಬಳಕೆಯಾಗಿದೆ. ಪುರುಷೋತ್ತಮ ಎಂದರೆ ಕ್ಷರ(ಜೀವ)ವನ್ನು ಮೀರಿನಿಂತವನು. ಅಕ್ಷರ(ಶ್ರೀತತ್ವ)ಕ್ಕಿಂತಲೂ\nಹಿರಿಯನು. “ಕ್ಷರ-ಅಕ್ಷರವನ್ನು ಮೀರಿ ನಿಂತ ನೀನಲ್ಲದೆ ನಿನ್ನಿಂದ ಹಿರಿದಾದ ತತ್ವ ಇನ್ನೊಂದಿಲ್ಲ. ಆದ್ದರಿಂದ ಇದರ\nವಿವರಣೆಯನ್ನು ನಿನ್ನಿಂದ ತಿಳಿಯಬೇಕು” ಎನ್ನುವ ಭಾವವನ್ನು ಅರ್ಜುನ ವ್ಯಕ್ತಪಡಿಸಿದ ಎನ್ನುವುದನ್ನು ಈ\nಸಂಬೋಧನೆ ತಿಳಿಸುತ್ತದೆ.\n\nಇಲ್ಲಿ ಅರ್ಜುನ ಕೃಷ್ಣನನ್ನು- ಭೂತಭಾವನ, ಭೂತೇಶ, ದೇವದೇವ ಮತ್ತು. ಜಗತ್‌ ಪತೇ ಎಂದು\nಸಂಬೋಧಿಸಿದ್ದಾನೆ. ಭೂತಭಾವನ ಎಂದರೆ- ಪಂಚಭೂತಾತ್ಮಕ ಪ್ರಪಂಚವನ್ನು ಸೃಷ್ಟಿ ಮಾಡಿ, ಸಮಸ್ತ ಜೀವ-\nಜಾತದ ಸೃಷ್ಟಿ-ಸ್ಥಿತಿ-ಸಂಹಾರಕ್ಕೆ ಕಾರಣನಾಗಿರುವವ. ಭೂತೇಶ ಎಂದರೆ- ಎಲ್ಲರನ್ನೂ ನಿಯಂತ್ರಿಸುವ ಸರ್ವ\nನಿಯಾಮಕ ಸ್ವಾಮಿ. ದೇವದೇವ ಎಂದರೆ-ಎಲ್ಲಾ ದೇವತೆಗಳಿಗೂ ದೇವನಾಗಿರುವವ; ಸೂರ್ಯಾದಿಗಳಿಗೂ\nಬೆಳಕನ್ನು ಕೊಡುವ ಮೂಲ ಜ್ಯೋತಿ. ಜಗತ್‌ ಪತಿ ಎನ್ನುವಲ್ಲಿ 'ಪತಿ' ಎಂದರೆ ಪಾಲಕ. ಹುಟ್ಟಿಸುವವನೂ\nಭಗವಂತ, ಸಾಯಿಸುವವನೂ ಭಗವಂತ. ಹುಟ್ಟು ಸಾವಿಲ್ಲದ ಮೋಕ್ಷ ಕೊಡುವವನೂ ಅವನೇ. ಆತ ಸಮಸ್ತ\nಜಗತ್ತಿನ ಪಾಲಕ. ನಮಗೆ ಭಗವಂತ “ಸಂಸಾರಬಂಧ' ಕೊಡುವುದು ಆತನ ಪಾಲನೆಯ, ಶಿಕ್ಷಣದ ಒಂದು ಮುಖ\nಅಷ್ಟೇ. ಒಟ್ಟಿನಲ್ಲಿ “ನೀನಿಲ್ಲದೆ ನಾವಿಲ್ಲ, ನೀನೇ ಸರ್ವ ರಕ್ಷಕ” ಎನ್ನುವ ಭಾವವನ್ನು ಅರ್ಜುನ ಈ ಮೂಲಕ\nವ್ಯಕ್ತಪಡಿಸಿದ್ದಾನೆ.\n",
  "10.17": "ಕಥಮ್‌ ವಿದ್ಯಾಮ್‌ ಅಹಮ್‌ ಯೋಗಿನ್‌ ತ್ವಾಮ್‌ ಸದಾ ಪರಿಚಿಂತಯನ್‌ |\n\nಕೇಷುಕೇಷು ಚ ಭಾವೇಷು ಚಿಂತ್ಯಃ ಅಸಿ ಭಗವನ್‌ ಮಯಾ-ಸರ್ವಸಮರ್ಥನೆ, ನಿನ್ನನ್ನು ಅನುಗಾಲ ಹೇಗೆ\nಪರಿಪರಿ ನೆನೆಯುತ್ತಾ ನಾನು ತಿಳಿಯಬಹುದು? ಓ ಭಗವನ್‌, ಯಾವಯಾವ ವಸ್ತುಗಳಲ್ಲಿ ಹೇಗಿರುವೆಯೆಂದು\nನಾನು ನೆನೆಯಬೇಕು?\n\nಈ ಪ್ರಪಂಚದ ಪ್ರತಿಯೊಂದು ವಸ್ತುವಿನಲ್ಲಿರುವ ಒಂದು ವಿಶಿಷ್ಟ ಗುಣದ ಹಿಂದೆ ಭಗವಂತನ ವಿಭೂತಿ ಅಡಗಿದೆ.\nಇಲ್ಲಿ ಅರ್ಜುನ ಭಗವಂತನಲ್ಲಿ ಪ್ರಾರ್ಥಿಸುತ್ತಾನೆ: “ಸರ್ವ ಸಮರ್ಥನಾದ ನೀನು ಎಲ್ಲಿ ಏನಾಗಿದ್ದಿ ಎಂದು ನಿನಗೆ\nತಿಳಿದಿದೆ ಹೊರತು ನನಗಲ್ಲ. ನಾನು ಒಂದು ವಸ್ತುವನ್ನು ಕಂಡಾಗ ಅದರ ಹಿಂದಿರುವ ಭಗವತ್‌ ಶಕ್ತಿಯ ನೆನಪು\nನನಗೆ ಬರಬೇಕು. ಯಾವಯಾವ ವಸ್ತುವಿನಲ್ಲಿ ನಿನ್ನ ಉಪಾಸನೆಯನ್ನು ನಾನು ಮಾಡಬಹುದು-ಅದನ್ನು ನಾನು\nತಿಳಿಯಬೇಕು” ಎಂದು.",
  "10.18": "ವಿಸ್ತರೇಣ ಆತ್ಮನಃ ಯೋಗಮ್‌ ವಿಭೂತಿಮ್‌ ಚ ಜನಾರ್ದನ ।\nಭೂಯಃ ಕಥಯ ತೃಷ್ತಿಃ ಹಿ ಶೃಣ್ವತಃ ನ ಅಸ್ತಿ ಮೇ ಅಮೃತಮ್‌--ಓ ಜನಾರ್ದನಾ, ನಿನ್ನ ಆಳವನ್ನೂ ಬಗೆಬಗೆಯ\nರೂಪಗಳ ಹಿರಿಮೆಯನ್ನೂ ಇನ್ನ ಷ್ಟು ಬಿತ್ತರಿಸಿ ಹೇಳು. ನನಗೆ ಈ ಸುಧೆಯನ್ನು ಎಷ್ಟು ಸವಿದರೂ ತಣಿವಿಲ್ಲ.\n\n“ನಿನ್ನ ವಿಭೂತಿಯನ್ನು ಇನ್ನೂ ಹೇಳು” ಎಂದು ಅರ್ಜುನ ಕೃಷ್ಣನನ್ನು ಕೇಳಿಕೊಳ್ಳುತ್ತಾನೆ. ಭಗವಂತನ\nವಿಭೂತಿಯಲ್ಲಿ ಪ್ರಮುಖವಾಗಿ ನಾಲ್ಕು ವಿಧ. (೧) ಸಾಕ್ಷಾತ್‌ ವಿಭೂತಿ: ಇಲ್ಲಿ ಭಗವಂತ ವಿಶಿಷ್ಟ ರೂಪದಲ್ಲಿ ನಮಗೆ\nಭೂಮಿಯ ಮೇಲೆ ಕಾಣಿಸಿಕೊಳ್ಳುತ್ತಾನೆ. ಉದಾಹರಣೆಗೆ: ಭಗವಂತನ ಅವತಾರಗಳು. (೨) ವಿಜಾತಿಯ\nಸ್ರಷ್ಟಪ್ರಭ. ಉದಾಹರಣೆಗೆ: ನಕ್ಷತ್ರಗಳ ರಾಜ ಚಂದ್ರ. ಇಲ್ಲಿ ಚಂದ್ರ ನಕ್ಷತ್ರಗಳ ಜಾತಿಗೆ ಸೇರಿಲ್ಲ ಆದರೆ ಆತ\nನಕ್ಷತ್ರಗಳ ರಾಜ. (೩)ಸ್ವಜಾತಿಯ ಸ್ರಷ್ಟಪ್ರಭ. ಉದಾಹರಣೆಗೆ: ದೇವತೆಗಳಲ್ಲಿ ಇಂದ್ರ, ಬೆಳಕಿನಲ್ಲಿ ಸೂರ್ಯ. (೪)\nಸ್ವಜಾತಿಯ ಏಕದೇಶೀಯ ಸ್ರಷ್ಟಪ್ರಭ. ಉದಾಹರಣೆಗೆ: ಪಾಂಡವರಲ್ಲಿ ಅರ್ಜುನ. ಹೀಗೆ ಈ ನಾಲ್ಕು ಬಗೆಯಲ್ಲಿ\nಭಗವಂತನ ವಿಭೂತಿ ರೂಪಗಳು ಅನಂತ. ಇಲ್ಲಿ ಎಲ್ಲವನ್ನೂ ನಾವು ಉಪಾಸನೆ ಮಾಡಲು ಸಾಧ್ಯವಿಲ್ಲ.\nಅದಕ್ಕಾಗಿ ಅರ್ಜುನ ಉಪಾಸನೆ ಮಾಡುವುದಕ್ಕೆ ಅನುಕೂಲವಾದ “ನಿನ್ನ ವಿಭೂತಿಯನ್ನು ವಿಸ್ತಾರವಾಗಿ ಹೇಳು”\nಎಂದು ಕೃಷ್ಣನಲ್ಲಿ ಕೇಳಿಕೊಳ್ಳುತ್ತಾನೆ.\n\nಅರ್ಜುನ ಕೃಷ್ಣನ ಸಂದೇಶವನ್ನು ಕೇಳಿ ಆನಂದ ಸಾಗರದಲ್ಲಿ ತೇಲುತ್ತಿದ್ದಾನೆ. ಆತ ಹೇಳುತ್ತಾನೆ: “ನಾನು\nಅಮೃತಪಾನ ಮಾಡುತ್ತಿದ್ದೇನೆ, ಇಲ್ಲಿ ಸಾಕು ಎನ್ನು ವುದಿಲ್ಲ” ಎಂದು. ಇದು ಮೋಕ್ಷಪ್ರದವಾದ, ಕಿವಿ",
  "10.19": "ಭಗವಾನ್‌ ಉವಾಚ-ಭಗವಂತ ನುಡಿದನು:\n\nಹಂತ ತೇ ಕಥಯಿಷ್ಯಾಮಿ ದಿವ್ಯಾಃ ಹಿ ಆತ್ಮ ವಿಭೂತಯಃ |\n\nಪ್ರಾಧಾನ್ಯತಃ ಕುರುಶ್ರೇಷ್ಠ ನ ಅಸ್ತಿ ಅಂತಃ ವಿಸ್ತರಸ್ಯ ಮೇ-ಕುರುಗಳ ಮುಂದಾಳೇ, ಭಲೆ! ನನ್ನ ಅಲೌಕಿಕವಾದ\nವಿಭೂತಿ ರೂಪಗಳಲ್ಲಿ ಕೆಲವನ್ನು ಆಯ್ದು ಹೇಳುತ್ತೇನೆ. ನನ್ನ ಬಿತ್ತರಕ್ಕೆ ಕೊನೆಯಿಲ್ಲ.\n\nಸಂಸ್ಕೃತದಲ್ಲಿ 'ಹಂತ' ಎನ್ನುವ ಪದ ಸಂತೋಷ ಮತ್ತು ವಿಸ್ಮಯವನ್ನು ವ್ಯಕ್ತಪಡಿಸಲು ಬಳಸುವ ಪದ. ಕೃಷ್ಣ\nಅರ್ಜುನನ ಆಸಕ್ತಿಯನ್ನು ಕಂಡು ಆತನನ್ನು “ಭಲೆ' ಎಂದು ಹೊಗಳುತ್ತಾನೆ.\n\nಇಂದು ಯಾರಿಗೂ ವೇದಾಂತ ಕೇಳುವ ಇಚ್ಛೆ ಇಲ್ಲ. “ನಮಗೆ ಸಮಯವಿಲ್ಲ” ಎಂದು ಜಾರಿಕೊಳ್ಳುವವರೇ\nಹೆಚ್ಚಾಗಿದ್ದಾರೆ. ಮಾನಸಿಕವಾಗಿ ನೋಡಿದರೆ 'ಸಮಯವಿಲ್ಲ' ಎನ್ನುವುದು ತಮಗೆ ಇಷ್ಟವಿಲ್ಲ ಎನ್ನುವುದನ್ನು\nಮುಚ್ಚಿಡಲು ಬಳಸುವ ಪದ! ನಮಗೆ ಇಷ್ಟವಿದ್ದರೆ ಸಮಯವಿರುತ್ತದೆ! ಇಲ್ಲಿ ಅರ್ಜುನನ ಕಾತರತೆಯನ್ನು ಕೃಷ್ಣ\nಪ್ರಶಂಸಿಸುತ್ತಾನೆ ಮತ್ತು “ನೀನು ಕೇಳಬೇಕೆಂದು ಬಯಸಿದ್ದನ್ನು ಖಂಡಿತವಾಗಿಯೂ ಹೇಳುತ್ತೇನೆ” ಎನ್ನುತ್ತಾನೆ.\nಭಗವಂತನ ವಿಭೂತಿ ದಿವ್ಯವಾದದ್ದು ಮತ್ತು ಅದು ಅನಂತ. ಅದನ್ನು ಪೂರ್ಣ ವಿಸ್ತಾರವಾಗಿ ಹೇಳಲು ಸಾಧ್ಯವಿಲ್ಲ.\nಇಲ್ಲಿ ಕೃಷ್ಣ ನಾವು ಮುಖ್ಯವಾಗಿ ಉಪಾಸನೆ ಮಾಡಬೇಕಾದ ಭಗವಂತನ ವಿಭೂತಿಯನ್ನು ಸಂಕ್ಷಿಪ್ತವಾಗಿ ಸಂಗ್ರಹ\nಮಾಡಿ ಹೇಳಿದ್ದಾನೆ.\n\nಇಲ್ಲಿ 'ಕುರುಶ್ರೇಷ್ಠ' ಎನ್ನುವ ವಿಶೇಷಣ ಬಳಕೆಯಾಗಿದೆ. ತಮ್ಮನ್ನು ತಾವು ಭಗವದುಪಾಸನೆ ದಾರಿಯಲ್ಲಿ\nತೊಡಗಿಸಿಕೊಂಡ ಸಾಧಕರು ಕುರುಗಳು'. ಇದು ಅಧ್ಯಾತ್ಮಕ್ಕೆ ಬೇಕಾದ ಕನಿಷ್ಠ ಅರ್ಹತೆ. “ನೀನು ಅಧ್ಯಾತ್ಮ\nಸಾಧನೆಯಲ್ಲಿ ಎತ್ತರಕ್ಕೇರಿದವನು. ನಿನಗೆ ಈ ಸಾಧನೆಯಲ್ಲಿ ಕಳಕಳಿ ಇದೆ. ಅದಕ್ಕಾಗಿ ನಿನಗೆ ಖಂಡಿತವಾಗಿ\nಹೇಳುತ್ತೇನೆ” ಎನ್ನುವ ಭಾವ ಈ ಸಂಬೋಧನೆಯ ಹಿಂದಿದೆ.\n",
  "10.20": "ಅಹಮ್‌ ಆತ್ಮಾ ಗುಡಾಕೇಶ ಸರ್ವಭೂತ ಆಶಯಸ್ಥಿತಃ |\n\nಅಹಮ್‌ ಆದಿಃ ಚ ಮಧ್ಯಮ್‌ ಚ ಭೂತಾನಾಮ್‌ ಅಂತಃ ಏವ ಚ-ಓ ಗುಡಾಕೇಶಾ, ಎಲ್ಲಾ ಗುಣಗಳ ನೆಲೆಯಾದ\nನಾನೇ ಎಲ್ಲಾ ಜೀವಿಗಳ ಹೃದಯದಲ್ಲಿ ನೆಲೆಸಿರುವ ಅಂತರ್ಯಾಮಿ. ನಾನೇ ಎಲ್ಲಾ ಜೀವಿಗಳ ಬುಡ, ನಡು ಮತ್ತು\nಕೊನೆ.\n\nವಿಭೂತಿಯ ಒಟ್ಟು ಸಾರ(essence) ಏನೆಂದರೆ: ಭಗವಂತ ಎಲ್ಲರ ಒಳಗೂ ತುಂಬಿದ್ದಾನೆ' ಎನ್ನುವುದು. ಕೃಷ್ಣ\nಹೇಳುತ್ತಾನೆ: “ನಾನು ಪ್ರತಿಯೊಂದು ಜೀವಿಯ ಒಳಗೆ ಆತ್ಮವಾಗಿ ತುಂಬಿದ್ದೇನೆ. ಎಲ್ಲಾ ಜೀವಗಳ ಆತ್ಮ ನಾನು”\nಎಂದು. ಈ ಶ್ಲೋಕದಲ್ಲಿ “ಜೀವಾತ್ಮ-ಪರಮಾತ್ಮ ಒಂದೇ' ಎಂದು ಹೇಳಲಾಗಿದೆ ಎಂದು ಕೆಲವರು ತಪ್ಪಾಗಿ\nತಿಳಿದುಕೊಳ್ಳುತ್ತಾರೆ. ಆದರೆ ಇಲ್ಲಿ ಕೃಷ್ಣ ಹೇಳಿರುವುದು 'ಜೀವಾತ್ಮರ ಆತ್ಮನಾಗಿ ನಾನು ತುಂಬಿದ್ದೇನೆ' ಎಂದೇ\nಹೊರತು 'ನಾನೇ ಜೀವಾತ್ಮ' ಎಂದಲ್ಲ. ಇದು ಪ್ರತಿಯೊಂದು ಜೀವರ ಒಳಗೆ ಅಂತರ್ಯಾಮಿಯಾಗಿರುವ\nಬಿಂಬರೂಪಿ ಭಗವಂತನನ್ನು ಹೇಳುತ್ತದೆ. ಭಗವಂತ “ಸರ್ವಭೂತಾಶಯಸ್ಥಿತಃ. ಸಮಸ್ತ ಜೀವಜಾತದ\nಹೃದಯಗುಹೆಯಲ್ಲಿ ಅಂತರ್ಯಾಮಿಯಾಗಿ ನಿಂತಿದ್ದಾನೆ ಆ ಹೃತ್ಕಮಲ ಮಧ್ಯ ನಿವಾಸಿ. ಇದು ಭಗವಂತನ ಅತಿ\nದೊಡ್ಡ ವಿಭೂತಿ. ಅನಂತ ಜೀವರೊಳಗೆ ಅನಂತ ವಿಭೂತಿ ರೂಪದಲ್ಲಿ ಭಗವಂತ ವ್ಯಕ್ತನಾಗುತ್ತಾನೆ. ಈ\nಕಾರಣದಿಂದ ನಾವು ಒಂದೊಂದು ಜೀವರಲ್ಲಿ ಒಂದೊಂದು ಶಕ್ತಿ ವೈಶಿಷ್ಟ್ಯವನ್ನು ಕಾಣುತ್ತೇವೆ. ಸಮಸ್ತ ಜೀವಗಳು-\nಹುಟ್ಟುವ ಮುಂಚೆ ಅವುಗಳ ಒಳಗೆ ನಿಯಾಮಕನಾಗಿ ನಿಂತು, ಅವುಗಳ ಸೃಷ್ಟಿಗೆ ಕಾರಣನಾಗಿ, ಅವುಗಳನ್ನು\nರಕ್ಷಣೆ ಮಾಡಿ, ಪ್ರಳಯಕಾಲದಲ್ಲೂ ಕೂಡಾ ಎಲ್ಲವನ್ನೂ ಕಾಪಾಡುವ ಭಗವಂತ-ಎಲ್ಲಾ ಅವಸ್ಥೆಗಳಲ್ಲಿಯೂ ಒಳಗೆ\nನಿಂತು ರಕ್ಷಿಸುವ ಶಕ್ತಿ.\n\nಇಲ್ಲಿ ಗುಡಾಕೇಶ ಎನ್ನು ವ ವಿಶೇಷಣ ಬಳಸಲಾಗಿದೆ. ಇದು ಕೂಡಾ ಒಂದು ವಿಭೂತಿ ಗಮಕ. 'ಗುಡಾಕ' ಎಂದರೆ\nನಿದ್ದೆ. 'ಗುಡಾಕೇಶ' ಎಂದರೆ ನಿದ್ದೆಯನ್ನು ಗೆದ್ದವ. ಅರ್ಜುನನಲ್ಲಿ ಈ ವಿಶೇಷ ಸಾಮರ್ಥ್ಯವಿತ್ತು. ಅದಕ್ಕಾಗಿ\nಆತನನ್ನು ಈ ನಾಮದಿಂದ ಕರೆಯುತ್ತಿದ್ದರು. “ನಿನ್ನೊಳಗೆ ನಿದ್ದೆಯನ್ನು ಗೆಲ್ಲುವ ಶಕ್ತಿಯಾಗಿ ತುಂಬಿರುವವನೂ\nನಾನೇ” ಎನ್ನುವ ಧ್ವನಿ ಈ ಸಂಬೋಧನೆಯಲ್ಲಿದೆ. ಈ ಅಧ್ಯಾಯದ ಮುಂದಿನ ಭಾಗದಲ್ಲಿ ಕೃಷ್ಣ ತನ್ನ ವಿಶಿಷ್ಟವಾದ\nವಿಭೂತಿಯನ್ನು ವಿವರಿಸುತ್ತಾನೆ.",
  "10.21": "ಆದಿತ್ಯಾನಾಮ್‌ ಅಹಮ್‌ ವಿಷ್ಣುಃ ಜ್ಯೋತಿಷಾಮ್‌ ರವಿಃ ಅಂಶುಮಾನ್‌।\n\nಮರೀಚಿಃ ಮರುತಾಮ್‌ ಅಸ್ಮಿ ನಕ್ಷತ್ರಾಣಾಮ್‌ ಅಹಮ್‌ ಶಶೀ-ಹನ್ನೆರಡು ಮಂದಿ ಅದಿತಿಯ ಮಕ್ಕಳಲ್ಲಿ [ಎಲ್ಲೆಡೆ\nಹಬ್ಬಿರುವುದರಿಂದ, ಎಲ್ಲದರೊಳಗೂ ತುಂಬಿರುವುದರಿಂದ] ವಿಷ್ಣುನಾಮಕ[ವಾಮನ]ನಾನು. ಬೆಳಗಿಸುವ\nಶಕ್ತಿಗಳಲ್ಲಿ ಕಿರಣಗಳಿಂದ ಬೆಳಗುವ ಹಿರಿಯ ಬೆಳಕು ರವಿ ನಾನು.[ರವ-ನಾದಗಳಿಂದ, ಇಂಜ್ಜೇಯನಾಗಿ “ರವಿ'\n\nಎಂಬ ಹೆಸರಿನಿಂದ ರವಿಯಲ್ಲಿದ್ದೇನೆ.] ಮರುತ್ತುಗಳ ಸಂತತಿಯಲ್ಲಿ ಮರೀಚಿ ನಾನು, [ಮರಿ-ನೀರು ತುಂಬಿದ\nಮೊಡಗಳನ್ನು, ಚಿಪ್ರಚೋದಿಸುವುದರಿಂದ \"ಮರೀಚಿ' ಎನ್ನಿಸಿ ಪ್ರವಹವಾಯುತನಯ ಮರೀಚಿಯಲ್ಲಿದ್ದೇನೆ.]\nನಕ್ಷತ್ರಗಳ ಒಡೆಯ ಚಂದ್ರ [ಶ ನಎಲ್ಲಾ ಸುಖಗಳಿಗಿಂತ, ಶಿ-ಅಧಿಕ ಸುಖರೂಪನಾಗಿ \"ಶಶಿ'ಎನಿಸಿ ಚಂದ್ರನಲ್ಲಿದ್ದು\nಅವನಿಗೆ ನಕ್ಷತ್ರಗಳ ಒಡೆತನವಿತ್ತವನು ನಾನು.\n\nತನ್ನ ವಿಭೂತಿಗಳ ಬಗ್ಗೆ ಹೇಳುತ್ತಾ ಕೃಷ್ಣ ಮೊಟ್ಟಮೊದಲು ನಿತ್ಯ ಉಪಾಸನೆಯಲ್ಲಿ ಬಹಳ ಮುಖ್ಯವಾದ ತನ್ನ\nಸ್ವರೂಪ ವಿಭೂತಿಯನ್ನು ಹೇಳುತ್ತಾನೆ. ಅದಿತಿಯ ಹನ್ನೆರಡು ಮಂದಿ ಪುತ್ರರಲ್ಲಿ (ದ್ವಾದಶಾದಿತ್ಯರು-\nವಿವಸ್ವಾನ್‌(ಸೂರ್ಯ), ಅರ್ಯಮಾ, ಪೂಷಾ, ತ್ವಷ್ಟಾ, ಸವಿತಾ, ಭಗ, ಧಾತಾ, ವಿಧಾತ, ವರುಣ, ಮಿತ್ರ, ಇಂದ್ರ,\nಮತ್ತು ವಾಮನರೂಪಿ ವಿಷ್ಣು) ಒಬ್ಬ ಭಗವಂತನ ಸಾಕ್ಷಾತ್‌ ವಿಭೂತಿ. ಆತನೇ ವಾಮನ ರೂಪಿ ವಿಷ್ಣು. ಆದ್ದರಿಂದ\nಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ದ್ವಾದಶಾದಿತ್ಯರಲ್ಲಿ ವಿಷ್ಣು ನಾನು” ಎಂದು. ಇನ್ನು ಆದಿತ್ಯರು ಎಂದರೆ ಸಮಸ್ತ ದೇವತೆಗಳು\nಎನ್ನುವ ಅರ್ಥವಿದೆ. ಸರ್ವ ದೇವತೆಗಳಲ್ಲಿ ದೇವೋತ್ತಮ 'ವಿಷ್ಣು' ಆ ಭಗವಂತ.\n\nಈ ಅಧ್ಯಾಯದಲ್ಲಿ ಬರುವ ಪ್ರತಿಯೊಂದು ನಾಮ ಕೂಡಾ ಭಗವಂತನ ವಿಭೂತಿ ನಾಮ. ಆದ್ದರಿಂದ\nಪ್ರತಿಯೊಂದು ನಾಮದ ಹಿಂದೆ ಅನೇಕ ಅರ್ಥನಿಷ್ಟತ್ತಿ(etymological tradition) ಅಡಗಿದೆ. ಈ ಶ್ಲೋಕದಲ್ಲಿ\nಬಂದಿರುವ ಮೊದಲ ಭಗವಂತನ ವಿಭೂತಿ ನಾಮ “ವಿಷ್ಣುಃ. ವಿಷ್ಣು ಎನ್ನುವ ನಾಮ ಏನನ್ನು ಹೇಳುತ್ತದೆ ಎಂದು\nಸಂಕ್ಷಿಪ್ತವಾಗಿ ನೋಡೋಣ: ಪುರಾಣದಲ್ಲಿ, ಭಾರತದಲ್ಲಿ ಬಂದಿರತಕ್ಕಂತಹ ಪೌರಾಣಿಕ ಅರ್ಥ ನೋಡಿದರೆ\nಮೂರು ಧಾತುವಿನಿಂದ 'ವಿಷ್ಣುಃ ಶಬ್ದ ನಿಷ್ಟನ್ನವಾಗಿದೆ. ಎನ್ನುವುದು ತಿಳಿಯುತ್ತದೆ. (೧) ವಿಷಲ್‌-ವ್ಯಾಪ್ತೋ (೨)\nವಿಷತಿ-ಪ್ರವೇಶೇ (೩) ವೇತಿ- ಪ್ರಜನಯತಿ, ಗತಿ, ಕಾಂತಿ, ಕಾದನೇಷು, ಗಚ್ಛತಿ. ಈ ಧಾತುವಿನ ಅರ್ಥದಲ್ಲಿ\nನೋಡಿದಾಗ-ವಿಷ್ಣುಃ ಎಂದರೆ ಎಲ್ಲಾ ಕಡೆ ತುಂಬಿದವನು(ವ್ಯಾಪು. ಆತ ಎಲ್ಲದರ ಹೊರಗೂ ಮತ್ತು ಎಲ್ಲದರ\nಒಳಗೂ ಪ್ರವೇಶ) ತುಂಬಿರುವುದರಿಂದ ಆತ ವಿಷ್ಣುಃ. ಇದನ್ನು ನಾರಾಯಣ ಸೂಕ್ತದಲ್ಲಿ “ಅಂತರ್‌ ಬಹಿಶ್ಚ ತತ್‌\nಸರ್ವಂ ವ್ಯಾಪ್ಯ ನಾರಾಯಣ ಸ್ಥಿತಃ” ಎಂದಿದ್ದಾರೆ. ಇನ್ನು \"ವೇತೀತಿ-ವಿಷ್ಣುಃ. .. ಎಲ್ಲರು ಯಾರನ್ನು\nಆಶ್ರಯಿಸಿಕೊಂಡಿದ್ದಾರೋ ಅವನು ವಿಷ್ಣು-ಸರ್ವಾಶ್ರಯಧಾತ ಭಗವಂತ. 'ವೇತಿ-ಪ್ರಜನಯತಿ'-ಯಾರು ಇಡೀ\nಪ್ರಪಂಚವನ್ನು ಸೃಷ್ಟಿ ಮಾಡಿದನೋ ಅವನು ವಿಷ್ಣು. ವೇತಿ-ಗತಿ'- ಎಲ್ಲರನ್ನು ರಕ್ಷಣೆ ಮಾಡುವ ಸರ್ವ ರಕ್ಷಕ\nಭಗವಂತ ವಿಷ್ಣು. 'ವೇತಿ-ಕಾಂತಿ(ಇಚ್ಛೆ)-ಇಡೀ ಜಗತ್ತನ್ನು ರಕ್ಷಿಸಿ ಉದ್ಧಾರ ಮಾಡಬೇಕು ಎನ್ನುವ ಸತ್ಯ ಸಂಕಲ್ಪ\nಇರುವವ ವಿಷ್ಣು. 'ವೇತಿ-ಕಾದನೇಶು'-ಸಮಸ್ತ ಜಗತ್ತನ್ನು ಯಾರು ಸಂಹಾರ ಮಾಡುತ್ತಾನೋ ಅವನು ವಿಷ್ಣು.\n'ವೇತಿ-ಗಚ್ಛತಿ'- ಮೂರು ಹೆಜ್ಜೆಯಿಂದ ತ್ರಿವಿಕ್ರಮನಾಗಿ ಮೂರು ಲೋಕವನ್ನು ಯಾರು ವ್ಯಾಪಿಸುತ್ತಾನೋ ಅವನು\nವಿಷ್ಣು. ಸಮಪ್ಟಿಯಾಗಿ ವಿಷ್ಣು ಎಂದರೆ “ದೇವರು' ಎನ್ನುವ ಅರ್ಥವನ್ನು ಕೊಡುತ್ತದೆ. ಇವು ನಾವು ವಿಷ್ಣುಃ ಶಬ್ದದಿಂದ\nಅನುಸಂಧಾನ ಮಾಡಬೇಕಾದ ಕೆಲವು ಅರ್ಥಗಳು. ಇದನ್ನು ಮಹಾಭಾರತದಲ್ಲಿ ಒಂದು ಕಡೆ ನಾಮಗಳ\nನಿರ್ವಚನದಲ್ಲಿ ಹೇಳಿದ್ದಾರೆ. ಈ ನಿರ್ವಚನ ಭಾರತದಲ್ಲಿ ಅರ್ಜುನನಿಗೆ ಕೃಷ್ಣನೇ ಹೇಳಿದ ನಿರ್ವಚನ. ಒಟ್ಟಿನಲ್ಲಿ\n“ಎಲ್ಲರಿಗೂ ಆಶ್ರಯನಾದ, ಎಲ್ಲರ ಸೃಷ್ಟಿ-ಸ್ಥಿತಿ-ಸಂಹಾರಕ್ಕೆ ಕಾರಣನಾದ, ಎಲ್ಲದರ ಒಳಗೂ-ಹೊರಗೂ\nತುಂಬಿರುವ, ಮೂರು ಹೆಜ್ಜೆಯಿಂದ ಮೂರು ಲೋಕವನ್ನು ಅಳೆದ ವಿಷ್ಣು ನಾನು” ಎಂದು ತನ್ನ ಸ್ವರೂಪ\nವಿಭೂತಿಯನ್ನು ಕೃಷ್ಣ ವಿವರಿಸಿದ್ದಾನೆ.\n\nಸ್ವರೂಪ ವಿಭೂತಿಯನ್ನು ಹೇಳಿದ ಕೃಷ್ಣ, ನಂತರ ವಿಷ್ಣುವಿನ ಉಪಾಸನೆಗೆ ಅತ್ಯಂತ ಹಿರಿದಾದ ಪ್ರತೀಕ\n'ಸೂರ್ಯ'ನಲ್ಲಿ ತನ್ನ ವಿಭೂತಿಯನ್ನು ವಿವರಿಸುತ್ತಾನೆ. ನಾವು ಗಾಯತ್ರಿ ಪ್ರತಿಪಾದ್ಯನಾದ ವಿಷ್ಣುವನ್ನು\nಸೂರ್ಯನಲ್ಲಿ ಉಪಾಸನೆ ಮಾಡುತ್ತೇವೆ. ಇದು ಸೌರಶಕ್ತಿಯಲ್ಲಿ ಭಗವಂತನ ಉಪಾಸನೆ. ಇದು ಭಗವಂತನ\nವಿಭೂತಿಯ ಎರಡನೇ ಮಜಲು. ಅದಕ್ಕಾಗಿ ವಿಷ್ಣುವಿನ ನಂತರ 'ರವಿ'ಯನ್ನು ಕೃಷ್ಣ ಪ್ರಸ್ತಾಪಿಸುತ್ತಾನೆ. ಸೂರ್ಯ\nನಮ್ಮ ಕಣ್ಣಿಗೆ ಕಾಣುವ ಜ್ಯೋತಿಗಳಲ್ಲೇ ಅತ್ಯಂತ ದೊಡ್ಡ ಜ್ಯೋತಿ. ಸೂರ್ಯನಲ್ಲಿ 'ರವಿ' ನಾಮಕನಾಗಿ\nತುಂಬಿರುವ ಭಗವಂತ ಸೌರಶಕ್ತಿಯಾಗಿ ವಿಶ್ವದಲ್ಲಿ ವ್ಯಾಪಿಸಿದ್ದಾನೆ.\n\nಇಲ್ಲಿ ಬಂದಿರುವ ಭಗವಂತನ ವಿಭೂತಿ ನಾಮ “ರವಿಃ. ರವ-ಇ-ರವದಿಂದ ತಿಳಿಯಲ್ಪಡುವವನು-ರವಿ. “ರವ'\nಎಂದರೆ ನಾದ. ಯಾರು ಗಾಯತ್ರಿ “ರವ'ದಿಂದ ಜ್ಞ್ಛೇಯನೋ ಅವನು ರವಿಃ ಬೆಳಕುಗಳಿಗೆ ಬೆಳಕು ಕೊಡುವ\nಭಗವಂತ, ಗಾಯತ್ರಿ ಪ್ರತಿಪಾದ್ಯನಾಗಿ, 'ರವಿ' ನಾಮಕನಾಗಿ ಸೂರ್ಯನಲ್ಲಿ, ಸೂರ್ಯ ಕಿರಣದಲ್ಲಿ\nಸನ್ನಿಹಿತನಾಗಿದ್ದಾನೆ.\n\nಕೃಷ್ಣ ಹೇಳುವ ಮುಂದಿನ ವಿಭೂತಿ ಆಕಾಶದಲ್ಲಿ ವಾತಾವರಣದ ಬೇರೆಬೇರೆ ಪದರನ್ನು ನಿಯಮಿಸುವ\nಮರುತ್ತುಗಳ ಸಂತತಿಯ ಮರೀಚಿ. ಮೂಲಭೂತವಾಗಿ ಮರುತ್ತುಗಳು ನಲವತ್ತೊಂಬತ್ತು ಮಂದಿ. ಇವರಲ್ಲಿ ಹತ್ತು\nಮಂದಿ ನಮ್ಮ ಪಿಂಡಾಂಡ ನಿಯಮನ ಮಾಡುವವರು. ಈ ಮರುತ್ತುಗಳ ನಿಯಮನ ಮಾಡುವವ\nಪ್ರವಹವಾಯು. ಪುರಾಣಗಳಲ್ಲಿ ಎಲ್ಲಿಯೂ ಈ ನಲವತ್ತೊಂಬತ್ತು ಮರುತ್ತುಗಳಲ್ಲಿ ಮರೀಚಿ ಎನ್ನುವ ಹೆಸರು\nಬಂದಿಲ್ಲ. ಆದ್ದರಿಂದ ಇಲ್ಲಿ ಮರೀಚಿ ಈ ನಲವತ್ತೊಂಬತ್ತು ಮರುತ್ತುಗಳಲ್ಲಿ ಒಬ್ಬ ಎಂದು ಹೇಳುವುದು ಕಷ್ಟ. ಆದರೆ\nಆತ ಪ್ರವಹವಾಯುವಿನ ಪುತ್ರ ಎನ್ನುವುದು ಸ್ಪಷ್ಟ. ಮಧ್ವಾಚಾರ್ಯರ ಐತರೇಯ ಉಪನಿಷತ್ತಿನ ಭಾಷ್ಯ ಮತ್ತು\nಗೀತಾ ತಾತ್ಪರ್ಯವನ್ನು ಸಮನ್ವಯ ಮಾಡಿ ನೋಡಿದರೆ-ಮರೀಚಿ ಹದಿನೆಂಟನೇ ಕಕ್ಷೆಯಲ್ಲಿರುವ ಭೂತವಾಯು\nದೇವತೆ. ಆದ್ದರಿಂದ ಈತ ಆಕಾಶ ಅಭಿಮಾನಿ ದೇವತೇೆ(ಗಣಪತಿ)ಯ ಸಮಾನಸ್ಕಂದ. ಭಗವಂತ\nಮರೀಚಿನಾಮಕನಾಗಿ ಭೂತವಾಯುವಿನ ಅಭಿಮಾನಿ ದೇವತೆಯೊಳಗೆ ವಿಭೂತಿಯಾಗಿ ನಿಂತಿದ್ದಾನೆ.\n\nಇಲ್ಲಿ ಬಂದಿರುವ ಭಗವಂತನ ವಿಭೂತಿ ನಾಮ 'ಮರೀಚಿ'. ಮರ ಎಂದರೆ ನೀರು. ಮರಿ ಎಂದರೆ ನೀರು\nತುಂಬಿರುವ ಮೋಡ. ಈ ಮೊಡವನ್ನು ಎಲ್ಲಿಗೆ ಕಳುಹಿಸಬೇಕೋ ಅಲ್ಲಿಗೆ ಸೇರಿಸುವ ವಾಯುವಿನಲ್ಲಿ\nಸನ್ನಿಹಿತನಾಗಿ, ಮಳೆ ಬರಿಸುವ ಶಕ್ತಿಯನ್ನು ಮರೀಚಿಗೆ ಕೊಟ್ಟು, ಅವನಲ್ಲಿ ವಿಭೂತಿ ರೂಪದಲ್ಲಿ ಕೂತ ಭಗವಂತ\nಮರೀಚಿ”.\n\nಆಕಾಶದಲ್ಲಿ ಸೂರ್ಯ ಮತ್ತು ವಾಯುವಿನಲ್ಲಿ ತನ್ನ ವಿಭೂತಿಯನ್ನು ಹೇಳಿದ ಕೃಷ್ಣ, ಮುಂದೆ ನಕ್ಷತ್ರಗಳ ರಾಜ\nಚಂದ್ರನಲ್ಲಿ ತನ್ನ ವಿಭೂತಿಯನ್ನು ವಿವರಿಸುತ್ತಾನೆ. ಇದು ವಿಜಾತಿಯ ಸ್ರಷ್ಟಪ್ರಭ ವಿಭೂತಿ. ನಕ್ಷತ್ರಗಳ ಒಡೆಯ\nಚಂದ್ರ. ಚಂದ್ರನಲ್ಲಿ ಎಲ್ಲಾ ನಕ್ಷತ್ರಗಳನ್ನು ನಿಯಮಿಸುವ ಶಕ್ತಿಯಾಗಿ “ಶಶಿ' ಶಬ್ದವಾಚ್ಯ ಭಗವಂತ ಕೂತು ಅವನಿಗೆ\nಆ ಶಕ್ತಿಯನ್ನು ಕೊಟ್ಟ.\n\nಇಲ್ಲಿ ಬಂದಿರುವ ಭಗವಂತನ ವಿಭೂತಿ ನಾಮ “ಶಶಿಃ'. ಶಶ ಉಳ್ಳವನು ಶಶಿ. 'ಶ' ಎಂದರೆ ಆನಂದ. ಶಶ ಎಂದರೆ\nಆನಂದದ ಆನಂದ-ಪರಮಾನಂದ. ಇಂತಹ ಪರಮಾನಂದ ಉಳ್ಳ ಭಗವಂತ ಆನಂದ ಮೂರ್ತಿಯಾಗಿ\nಚಂದ್ರನಲ್ಲಿ ಕೂತ. ಈ ಕಾರಣದಿಂದ ನಮಗೆ ಬೆಳದಿಂಗಳು ಆನಂದವನ್ನು ಕೊಡುತ್ತದೆ.\n",
  "10.22": "ವೇದಾನಾಮ್‌ ಸಾಮ ವೇದಃ ಅಸ್ಮಿ ದೇವಾನಾಮ್‌ ಅಸ್ಮಿ ವಾಸವಃ |\n\nಇಂದ್ರಿಯಾಣಾಮ್‌ ಮನಃ ಚ ಅಸ್ಮಿ ಭೂತಾನಾಮ್‌ ಅಸ್ಮಿ ಚೇತನಾ -ವೇದಗಳಲ್ಲಿ ಸಾಮವೇದ ನಾನು.\n[ಸಾಮ- ಎಲ್ಲೆಡೆಯೂ ಸಮನಾಗಿದ್ದು, ವೇದ ಜ್ಞಾನರೂಪನಾದ್ದರಿಂದ “ಸಾಮವೇದ' ಎನ್ನಿಸಿ\nಸಾಮವೇದದಲ್ಲಿದ್ದೇನೆ.] ದೇವತೆಗಳಲ್ಲಿ ಇಂದ್ರ ನಾನು. [ವಾಸ- ಎಲ್ಲಾ ನೆಲೆಗಳಲ್ಲೂ, ವಂಇರುವವನಾಗಿ-\n“ವಾಸವ' ಎನ್ನಿಸಿ ದೇವೇಂದ್ರನಲ್ಲಿದ್ದೇನೆ.] ಇಂದ್ರಿಯಗಳಲ್ಲಿ ಮನಸ್ಸು ನಾನು. [ಅರಿವು ನೀಡುವುದರಿಂದ “ಮನಸ್‌'\nಎನ್ನಿಸಿ ಮನಸ್ಸಿನಲ್ಲಿದ್ದೇನೆ.] ಜೀವಿಗಳ ಚೈತನ್ಯ ನಾನು. [ಚೇತಸ್‌ ಇಎಲ್ಲಾ ಜೀವಿಗಳ ನೆನಪಿನ ಗಂಟನ್ನು,\nನಾ:ಬಿಡಿಸುವುದರಿಂದ “ಚೇತನಾ' ಎನ್ನಿಸಿ ಚೇತನಾಶಕ್ತಿಯಲ್ಲಿದ್ದೇನೆ.]\n\nಆಕಾಶದಲ್ಲಿ-ಸೂರ್ಯ, ಚಂದ್ರ, ನಕ್ಷತ್ರ, ಗಾಳಿಯಲ್ಲಿ ತನ್ನ ವಿಭೂತಿಯನ್ನು ಹೇಳಿದ ಕೃಷ್ಣ, ಇಲ್ಲಿ ಆಕಾಶದ ವಿಶೇಷ\nಗುಣವಾದ ಶಬ್ದದ ಬಗ್ಗೆ ಹೇಳುತ್ತಾನೆ. ಶಬ್ದದ ವಿಭೂತಿ-ವೇದ. ವೇದದಲ್ಲಿ ವಿಶಿಷ್ಟವೇದ-ಸಾಮವೇದ.\nವೇದಗಳೆಲ್ಲವೂ ಅಪೂರ್ವವಾಗಿದ್ದರೂ ಕೂಡಾ, ಸಾಮವನ್ನು ಏಕೆ ವಿಶೇಷವಾಗಿ ಹೇಳಿದ್ದಾರೆ ಎನ್ನು ವ ಪ್ರಶ್ನೆ\nನಿಮ್ಮಲ್ಲಿ ಬರಬಹುದು. ವೇದದಲ್ಲಿ ತಾರತಮ್ಯವಿಲ್ಲ. ಆದರೆ ವೇದಾಭಿಮಾನಿಗಳಲ್ಲಿ ತಾರತಮ್ಯವಿದೆ.\nಸಾಮವೇದದ ಅಭಿಮಾನಿ ಪ್ರಾಣದೇವರು. ಶಾಸ್ತ್ರಕಾರರು ಹೇಳುವಂತೆ ಸಾಮಗಾನವನ್ನು ಅತ್ಯಂತ\nಮಧುರವಾಗಿ ಹಾಡುವವರು ಪ್ರಾಣದೇವರು. ಪ್ರಾಣದೇವರ ಹಾಡು 'ಸಾಮಗಾನ' ಭಗವಂತನಿಗೆ ಅತಿ ಇಷ್ಟ\nಸಾಮವೇದದ ವೈಶಿಷ್ಟ್ಯ “ನಾದ'. ಒಂದು ಶಬ್ದವನ್ನು ಹೇಗೆ ಒಡೆದರೂ, ಅದನ್ನು ಹೇಗೆ ಪದಪಾಠ ಮಾಡಿದರೂ,\nಅದರಲ್ಲಿ ಯಾವ ನಾದ ತುಂಬಿದರೂ, ಅದು ಭಗವಂತನ ನಾಮದೇಯವಾಗುತ್ತದೆ ಎನ್ನುವ ಪ್ರಯೋಗ\nಸಾಮವೇದ. ಋಗ್ವೇದ ಮತ್ತು ಯಜುರ್ವೇದದಲ್ಲಿ ಮಂತ್ರಗಳ ಹಾಗೂ ಶಬ್ದಗಳ ಮುಖೇನ ಭಗವಂತನ\nಸ್ತುತಿಯಾದರೆ, ಸಾಮವೇದದಲ್ಲಿ ಶಬ್ದದ ಜೊತೆಗೆ ನಾದವನ್ನು ಭಗವಂತನಲ್ಲಿ ಸಮನ್ವಯಗೊಳಿಸುವ ಅಪೂರ್ವ\nಗುಣಧರ್ಮವಿದೆ(unique quality). ಶಬ್ದಗಳ ಹಿಂದಿನ ನಾದದಿಂದ ಭಗವಂತನನ್ನು ಕಾಣುವ\nನಾದೋಪಾಸನೆ.. ಇರುವ ವೇದ ಸಾಮವೇದವಾದ್ದರಿಂದ-ಭಗವಂತ ಸಾಮದಲ್ಲಿ ವಿಶೇಷವಾಗಿ\nಸನ್ನಿಹಿತನಾಗಿದ್ದಾನೆ. ಆದ್ದರಿಂದ 'ಸಾಮ' ಭಗವಂತನ ಅನ್ವರ್ಥ ನಾಮ. ಎಲ್ಲಾ ಶಬ್ದಗಳು ಭಗವದ್‌ ಪರ\nಎನ್ನುವುದನ್ನು ಋಗ್ವೇದ ತೋರಿಸಿದರೆ, ಶಬ್ದವಷ್ಟೇ ಅಲ್ಲ, ಎಲ್ಲಾ ಘೋಷಗಳೂ ಭಗವಂತನನ್ನು ಹೇಳುತ್ತವೆ\nಎನ್ನುವುದನ್ನು ಸಾಮವೇದ ತೋರಿಸುತ್ತದೆ.\n\nಭಗವಂತ “ಸಾಮಃ' ಮತ್ತು ಆತ 'ವೇದಃ'. ಇಲ್ಲಿ 'ಸಾಮಃ' ಎಂದರೆ ಎಲ್ಲೆಡೆಯೂ ಸಮನಾಗಿರುವವ ಎಂದರ್ಥ.\n'ವೇದಃ' ಎಂದರೆ ಜ್ಞಾನ ರೂಪ. ಭಗವಂತ ನಾದವಾಗಿ ಸಾಮವೇದದಲ್ಲಿ ತುಂಬಿ ಅದನ್ನು ವಿಭೂತಿಯಾಗಿ\nಮಾಡಿದ.\n\nವೇದದ ನಂತರ ವೇದಪ್ರತಿಪಾದ್ಯ ದೇವತೆಗಳು. ದೇವತೆಗಳಲ್ಲಿ ಮುಖ್ಯವಾಗಿ ತತ್ತ್ವಾಭಿಮಾನಿ ದೇವತೆಗಳು.\nಭಗವಂತನ ಅಧಿಷ್ಠಾನವಾಗಿ ಇಂದ್ರಿಯಗಳನ್ನು ನಿಯಮಿಸುವ ದೇವತೆಗಳಲ್ಲಿ ಮುಖ್ಯನಾದವ \"ವಾಸವ'(ಇಂದ್ರ).\n\nಈತ ಬಾಹ್ಯೇಂದ್ರಿಯಾಭಿಮಾನಿ ದೇವತೆಗಳಲ್ಲಿ ಶ್ರೇಷ್ಠ. ಈತ ಐದು ಜ್ಞಾನೇಂದ್ರಿಯ(ಕಣ್ಣು, ಕಿವಿ, ಮೂಗು,\nನಾಲಿಗೆ, ಚರ್ಮ) ಮತ್ತು ಐದು ಕರ್ಮೇಂದ್ರಿಯ(ಕೈ, ಕಾಲು, ಬಾಯಿ, ಪಾಯು, ಉಪಸ್ಥ)ಗಳಲ್ಲಿ ಅತ್ಯಂತ\nವಿಶಿಷ್ಟವಾದ ಕೈ.\nಭಗವಂತ ನಮ್ಮೊಳಗಿದ್ದು, ಮನಸ್ಸು ಕಂಡದ್ದನ್ನು ಅರಿವಾಗಿ-ವಿಷಯವನ್ನು ಸ್ವೀಕರಿಸುವ ಗ್ರಹಣ ಶಕ್ತಿಯಾಗಿ\nಕೂತ. ಇದರಿಂದ ಪ್ರಪಂಚವನ್ನು ಗ್ರಹಣ ಮಾಡುವ ಶಕ್ತಿ ಜೀವಕ್ಕೆ ಬಂತು. ಇಡೀ ವಿಶ್ವವನ್ನು ತನ್ನ ಅರಿವಿನಿಂದ\nಗ್ರಹಣ ಮಾಡಿ, ವ್ಯಾಪಿಸುವ ವಿಸ್ಮಯ ಭಗವಂತ 'ಚೇತನಃ'. 'ಚೇತಸ್‌' ಎಂದರೆ ನಮ್ಮ ಸುಪ್ತಪ್ರಜ್ಞೆ. ನಮ್ಮ\nಪ್ರತಿಯೊಂದು ಅನುಭವ ನಮ್ಮ ಸುಪ್ಪಪ್ರಜ್ಞೆಯಲ್ಲಿ ಸಂಗ್ರಹವಾಗಿರುತ್ತದೆ. ಚಿತ್ತಕ್ಕೆ ಎಲ್ಲವನ್ನು ಗ್ರಹಿಸುವ ಶಕ್ತಿ\nಕೊಟ್ಟವ 'ಚೇತನಃ' ನಾಮಕ ಭಗವಂತ. ಇದು ಭಗವಂತನ ವಿಭೂತಿ.\n",
  "10.23": "ರುದ್ರಾಣಾಮ್‌ ಶಂಕರಃ ಚ ಅಸ್ಮಿ ವಿತ್ತ ಈಶಃ ಯಕ್ಷರಕ್ಷಸಾಮ್‌ |\n\nವಸೂನಾಮ್‌ ಪಾವಕಃ ಚ ಅಸ್ಮಿ ಮೇರುಃ ಶಿಖರಿಣಾಮ್‌ ಅಹಮ್‌-ರುದ್ರರಲ್ಲಿ [ಹನ್ನೊಂದು ಮಂದಿ] ಪ್ರಧಾನ ರುದ್ರ\nನಾನು. [ಶಂ-ಸುಖವನ್ನು, ಕರಾಕರುಣಿಸುವುದರಿಂದ “ಶಂಕರ' ಎನ್ನಿಸಿ ಶಂಕರನಲ್ಲಿದ್ದೇನೆ.] ಯಕ್ಷ-ರಾಕ್ಷಸರ\nಪಡೆಯ ಒಡೆಯ ಕುಬೇರ (ವಿತ್ತ-ಸಿರಿಗೆ, ಈಶ-ಒಡೆಯನಾದ್ದರಿಂದ 'ವಿತ್ತೇಶ' ಎನ್ನಿಸಿ ಕುಬೇರನಲ್ಲಿದ್ದು ಅವನಿಗೆ\nಯಕ್ಷ-ರಾಕ್ಷಸರ ಒಡೆತನವನ್ನಿತ್ತವನು] ನಾನು. [ಎಂಟು ಮಂದಿ] ವಸುಗಳಲ್ಲಿ ಅಗ್ನಿದೇವ ನಾನು.\n[ಪಾವನಗೊಳಿಸುವುದರಿಂದ 'ಪಾವಕ' ಎನ್ನಿ ಸಿ ಅಗ್ನಿ ಯಲ್ಲಿದ್ದೇನೆ.] ಚೆಲುಕೋಡಿನ ಬೆಟ್ಟಗಳಲ್ಲಿ ಮೇರು ನಾನು.\n[ಈರು-ಬೇರೊಬ್ಬ ಪ್ರೇರಕ, ಮಾ-ಇರದ್ದರಿಂದ \"ಮೇರು' ಎನ್ನಿಸಿ ಮೇರು ಗಿರಿಯಲ್ಲಿದ್ದೇನೆ.]\n\nಮನಸ್ಸಿನಲ್ಲಿನ ತನ್ನ ವಿಭೂತಿಯನ್ನು ಹೇಳಿದ ಕೃಷ್ಣ, ಇಲ್ಲಿ ಮನಸ್ಸಿನ ಅಭಿಮಾನಿಯಾದ ಶಿವನಲ್ಲಿ ತನ್ನ\nವಿಭೂತಿಯನ್ನು ವಿವರಿಸುತ್ತಾನೆ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ರುದ್ರರಲ್ಲಿ ಶಂಕರ ಸಾನು” ಎಂದು. ರುದ್ರರು ಹನ್ನೊಂದು\nಮಂದಿ. ರೈವತ, ಓಜ, ಭವ, ಭೀಮ, ವಾಮದೇವ, ಉಗ್ರ, ವೃಷಾಕಪಿ, ಅಜೈಕಪಾತ್‌, ಅಹಿರ್ಬುದ್ದಿ , ವಿರೂಪಾಕ್ಷ,\nಮತ್ತು ಗಣಪ್ರಧಾನನಾದ ಮಹಾದೇವ. (ಈ ಏಕಾದಶ ರುದ್ರರಿಗೆ ಒಬ್ಬೊಬ್ಬರಿಗೂ ಅನೇಕ ಹೆಸರುಗಳುಂಟು.\nಬೇರೆಬೇರೆ ಕಡೆ ಬೇರೆಬೇರೆ ಹೆಸರು ಉಲ್ಲೇಖ ಮಾಡಿದ್ದಾರೆ). ನಮ್ಮ ಮನಸ್ಸನ್ನು ನಿಯಂತ್ರಿಸುವ 'ರುದ್ರ'-\nಮಹಾದೇವ ಅಥವಾ ಶಿವ. ಆತನಿಗೆ 'ಶಂಕರ' ಎಂದು ಹೆಸರು. ರುದ್ರ ಎಂದರೆ ರೋದಯತಿ ಇತಿ ರುದ್ರಃ-ದುಃಖ\nಕೊಡುವವನು ಎನ್ನುವ ಒಂದು ಅರ್ಥ. ಭಗವಂತ ದುಃಖ ಕೊಡುವುದು ಕೇವಲ ದುಷ್ಟರಿಗೆ. ಇನ್ನೊಂದು ಅರ್ಥದಲ್ಲಿ\nನೋಡಿದರೆ- ರುಜಂ ದ್ರಾವಯತಿ ಇತಿ ರುದ್ರಃ ಅಂದರೆ ನಮ್ಮಲ್ಲಿರುವ ರೋಗವನ್ನು ಪರಿಹಾರ ಮಾಡಿ\nಸುಖಕೊಡುವವನು. ಮೂಲತಃ ರೋಗ ಮಾನಸಿಕ. ನಮ್ಮ ಮನಸ್ಸು ದೃಢವಾಗಿದ್ದರೆ ಕಾಯಿಲೆ ಬರುವುದಿಲ್ಲ.\nಒಂದು ವೇಳೆ ಕಾಯಿಲೆ ಬಂದರೆ ಅದನ್ನು ಎದುರಿಸಬಲ್ಲೆ ಎನ್ನುವ ದೃಢಮನಸ್ಸು ಇದ್ದರೆ-ಮನಸ್ಸೇ ಆ ರೋಗವನ್ನು\nಗುಣಪಡಿಸಬಲ್ಲದು.\n\n'ಶಂಕರ' ಎಂದರೆ ಸುಖವನ್ನು, ಸಂತೋಷವನ್ನು ಕೊಡುವವ. ಆರೋಗ್ಯವಂತ ದೇಹವೇ ಜೀವನದಲ್ಲಿ ಬಹಳ\nದೊಡ್ಡ ಸುಖ. ಯಾವುದೇ ಪುಣ್ಯ ಕರ್ಮ ಸಾಧನೆ ಮಾಡಲು ಆರೋಗ್ಯವಂತ ದೇಹ ಬೇಕು. 'ರುದ್ರ'\nಶರೀರಪುರುಷ. ಈ ದೇಹ ನಿಂತು ನಡೆದಾಡಬೇಕಾದರೆ ದೇಹದಲ್ಲಿ ಶರೀರಪುರುಷನಾದ ಶಿವಶಕ್ತಿ ಕಾರಣ. ನಮ್ಮ\nಮನಸ್ಸಿನಲ್ಲಿ ಕೂತು ಮಾನಸಿಕ ತುಮುಲವನ್ನು ಹೋಗಲಾಡಿಸಿ, ಆರೋಗ್ಯವಂತ ಶರೀರ ಕೊಟ್ಟು, ಆನಂದ\nಕೊಡುವವ ರುದ್ರ. ಋಗ್ವೇದದ ಶಿವಸ್ತುತಿಯಲ್ಲಿ ಶಿವನನ್ನು “ಭಿಶಕ್ತಮಾಂ ತ್ವ ಭಿಶಜಮ್‌” ಎಂದು ಸ್ತುತಿಸಿದ್ದಾರೆ.\nಅಂದರೆ “ನೀನು ವೈದ್ಯರ ವೈದ್ಯ” ಎಂದರ್ಥ. ಈ ಕಾರಣಕ್ಕಾಗಿ ಶಿವನನ್ನು 'ವೈದ್ಯನಾಥ' ಎಂದೂ ಕರೆಯುತ್ತಾರೆ.\nರುದ್ರನನ್ನು ಮಹಾದೇವ ಎಂದು ಕರೆಯಲು ಅನೇಕ ಕಾರಣವಿದೆ. ಇಲ್ಲಿ 'ದೇವ' ಅಂದರೆ ಇಂದ್ರಿಯ.(ದೇವತೀತಿ\nದೇವಂ ಇಂದ್ರಿಯಂ). ಶಿವ ಇಂದ್ರಿಯಾಭಿಮಾನಿ ದೇವತೆಗಳಲ್ಲಿ ಎಲ್ಲರಿಗಿಂತ ದೊಡ್ಡವ. ದೇವತಾ\nತಾರತಮ್ಯದಲ್ಲಿ ನೋಡಿದರೆ-ಹನ್ನೊಂದು ಮಂದಿ ರುದ್ರರಲ್ಲಿ ಹತ್ತುಮಂದಿ ರುದ್ರರು ಹದಿನೆಂಟನೇ ಕಕ್ಷೆಯಲ್ಲಿದ್ದರೆ,\n\nಶಿವ ಅದಕ್ಕಿಂತ ಬಹಳ ಎತ್ತರದಲ್ಲಿ ಐದನೇ ಕಕ್ಷೆಯಲ್ಲಿದ್ದಾನೆ. ಶಿವ ಭಗವಂತನ ಸಂಹಾರ ಕರ್ಮದಲ್ಲಿ\nವಾಯುದೇವರೊಂದಿಗೆ ಅಂಗಭೂತನಾಗಿ ಸಹಾಯಕಾರಿಯಾಗಿರುವ ಬಹಳ ದೊಡ್ಡ ಶಕ್ತಿ. ಭಗವಂತ “ಶಂಕರ'\nನಾಮಕನಾಗಿ ಶಿವನಲ್ಲಿ ನಿಂತಿದ್ದಾನೆ. ನಮ್ಮನ್ನು ಭಗವಂತನ ಉಪಾಸನೆಯ ದಾರಿಯಲ್ಲಿ ಕರೆದೊಯ್ದು, ಭಗವದ್‌\nಸಾಕ್ಷಾತ್ಕಾರಕ್ಕೆ ಮನಸ್ಸನ್ನು ಅಣಿಮಾಡುವವರೇ ರುದ್ರದೇವರು. ಆದ್ದರಿಂದ ಇದು ಭಗವಂತನ ಬಹಳ ದೊಡ್ಡ\nವಿಭೂತಿ.\n\nಇಲ್ಲಿ ಬಂದಿರುವ ಭಗವಂತನ ವಿಭೂತಿನಾಮ “ಶಂಕರಃ'. “ಶಂ' ಎಂದರೆ ಸುಖ, “ಕರ' ಎಂದರೆ ಕರುಣಿಸುವವ.\nಸ್ವಯಂ ಆನಂದ ಸ್ವರೂಪನಾಗಿದ್ದು, ದುಃಖಮಯವಾದ ಸಂಸಾರವನ್ನು ಖಂಡಿಸಿ- ನಮಗೆ ಮುಕ್ತಿ ಕೊಡುವ\nಭಗವಂತ “ಶಂಕರಃ',\n\nನಮ್ಮ ಅಂತರಂಗದ ಸಂಪತ್ತಿನ ಅಭಿಮಾನಿಯಾದ ಶಿವನ ಬಗ್ಗೆ ಹೇಳಿದ ಕೃಷ್ಣ, ಮುಂದೆ ನಮಗೆ ಬಾಹ್ಯವಿತ್ತವನ್ನು\nಕೊಡುವ ಕುಬೇರನಲ್ಲಿ ತನ್ನ ವಿಭೂತಿಯನ್ನು ವಿವರಿಸುತ್ತಾನೆ. ನಮ್ಮ ದೇಹದ ಅಭಿಮಾನಿ ಮತ್ತು ಬಾಹ್ಯವಿತ್ತದ\nಅಭಿಮಾನಿ ಕುಬೇರ. ಆತನ ಆಡಳಿತದಲ್ಲಿರುವವರು ಯಕ್ಷರು ಮತ್ತು ರಾಕ್ಷಸರು. ಯಕ್ಷರು ಎಂದರೆ ನರ\nಮಾಂಸವನ್ನು ನಿರ್ದಯವಾಗಿ ಭಕ್ಷಣೆ ಮಾಡುವವರು. ರಾಕ್ಷಸರು ಯಕ್ಷರಿಗಿಂತ ಉತ್ತಮರು. ಆದರೆ ಇವರೂ\nಕ್ರೂರಿಗಳು. ಇವರಿಂದ ನಾವು ನಮ್ಮನ್ನು ರಕ್ಷಣೆ ಮಾಡಿಕೊಳ್ಳಬೇಕು.\n\nಇಲ್ಲಿ ಬಂದಿರುವ ಭಗವಂತನ ವಿಭೂತಿನಾಮ 'ವಿತ್ತೇಶಃ'. ವಿತ್ತ ಎಂದರೆ ಸಿರಿ, ಈಶ ಎಂದರೆ ಒಡೆಯ. ಭಗವಂತ\n\"ವಿತ್ತೇಶ' ಎನ್ನಿಸಿ ಕುಬೇರನಲ್ಲಿದ್ದು, ಅವನಿಗೆ ಯಕ್ಷ-ರಾಕ್ಷಸರ ಒಡೆತನವನ್ನು ಕೊಟ್ಟ ಮತ್ತು ಆತನನ್ನು ಬಾಹ್ಯ\nಸಂಪತ್ತಿನ ಒಡೆಯನನ್ನಾಗಿ ಮಾಡಿದ. ಇದು ಕುಬೇರನಲ್ಲಿ ಭಗವಂತನ ವಿಶೇಷ ವಿಭೂತಿ.\n\nವೇದದಲ್ಲಿ ಬರುವ ದೇವತಾಗಣವನ್ನು ಪರಿಗಣನೆ. ಮಾಡುವಾಗ, ಆದಿತ್ಯ-ವಸು-ರುದ್ರಗಣ ಮೂರು\nಜೊತೆಜೊತೆಯಾಗಿ ಬರುತ್ತವೆ. ಮೂರು ಹೊತ್ತಿನ ಸವನದಲ್ಲಿ ಭಗವಂತನಿಗೆ ಆಹುತಿ ಕೊಡುವುದು ಕೂಡಾ ಈ\nದೇವತಾಗಣದಲ್ಲಿರುವ ಭಗವಂತನಿಗೆ. ಅಷ್ಟವಸುಗಳಲ್ಲಿ ಇರತಕ್ಕ ಭಗವಂತನಿಗೆ ಪ್ರಾತಃಕಾಲದಲ್ಲಿ ಅಷ್ಟಾಕ್ಷರ\nಮಂತ್ರ ಗಾಯತ್ರಿ ಮೂಲಕ ಆಹುತಿ ಕೊಡುತ್ತಾರೆ. ಮದ್ಯಾಹ್ನದ ಸವನ ಏಕಾದಶ ರುದ್ರರಿಗೆ ಸಂಬಂಧಪಟ್ಟದ್ದು.\nಇದಕ್ಕಾಗಿ ಇಲ್ಲಿ ಹನ್ನೊಂದು ಅಕ್ಷರದ 'ತ್ರಿಷ್ಟುಪ್‌' ಬಳಸುತ್ತಾರೆ. ಸಂಜೆಯ ಸವನ ದ್ವಾದಶಾಡಿತ್ಯರಿಗೆ\nಸಂಬಂಧಪಟ್ಟದ್ದು. ಅದಕ್ಕಾಗಿ ಅಲ್ಲಿ ದ್ವಾದಶಾಕ್ಷರದ “ಜಗತಿ'ಯನ್ನು ಬಳಸುತ್ತಾರೆ. ಕೃಷ್ಣ ಆದಿತ್ಯ ಮತ್ತು ರುದ್ರರ\nಬಗ್ಗೆ ಹೇಳಿದ. ಈಗ ಇಲ್ಲಿ ವಸುಗಳ ಬಗ್ಗೆ ಹೇಳುತ್ತಾ ಹೇಳುತ್ತಾನೆ: “ವಸುಗಳಲ್ಲಿ \"ಅಗ್ನಿ' ನಾನು” ಎಂದು. ವಸುಗಳು\nಎಂಟು ಮಂದಿ. ದ್ರೋಣ, ಪ್ರಾಣ, ಧ್ರುವ, ಅರ್ಕ, ಅಗ್ನಿ ದೋಷ, ವಸ್ತು ಮತ್ತು ವಿಭಾವಸು. ಇವರಿಗೆ ಇನ್ನೂ ಅನೇಕ\nಹೆಸರಿದೆ. ಐದನೆಯವನಾದ ಅಗ್ನಿಗೆ ವೈಶ್ವಾನರ, ವಹ್ನಿ, ಜಾತವೇದ, ಹುತಾಶನ, ಪಾವಕ, ಅನಲ, ದಹನ\nಇತ್ಯಾದಿ ಹೆಸರಿದೆ. ಇತರ ವಸುಗಳೆಲ್ಲರೂ ದೇವತಾ ತಾರತಮ್ಯದಲ್ಲಿ ಹದಿನೆಂಟನೇ ಕಕ್ಷೆಯಲ್ಲಿದ್ದರೆ, 'ಅಗ್ನಿ'\nಅವರಿಗಿಂತ ಎತ್ತರದಲ್ಲಿ ಹದಿನೈದನೇ ಕಕ್ಷೆಯಲ್ಲಿದ್ದಾನೆ. ಭೂಸ್ತರದಲ್ಲಿ ಭಗವಂತನನ್ನು ಆರಾಧನೆ ಮಾಡುವ ಶ್ರೇಷ್ಠ\nಪ್ರತೀಕ ಅಗ್ನಿ. ಇಡೀ ಜಗತ್ತನ್ನು ಪಾವನಗೊಳಿಸುವ ಶಕ್ತಿಯಾದ ಭಗವಂತ ಅಗ್ನಿಯಲ್ಲಿ 'ಪಾವಕಃ' ನಾಮಕನಾಗಿ\nಕೂತು ಆತನಿಗೆ ಈ ಶ್ರೇಷ್ಠ ಸ್ಥಾನವನ್ನು ಕೊಟ್ಟ.\n\nಅಗ್ನಿಯಲ್ಲಿ ಭಗವಂತನ ತೇಜಸ್ಸಿದೆ. ತೇಜಸ್ಸಿನಲ್ಲಿ ಬೆಳಕಿನ ಶಕ್ತಿಯಿದೆ, ಶಾಖ ಕೊಡುವ ಶಕ್ತಿಯಿದೆ. ಹಾಗೂ\nಸುಡುವ ಶಕ್ತಿಯೂ ಇದೆ. ಇಷ್ಟೇ ಅಲ್ಲದೆ ಈ ತೇಜಸ್ಸಿನಲ್ಲಿ ಪಚನ ಶಕ್ತಿಯಿದೆ. ಅಗ್ನಿಯ ಸಂಪರ್ಕಕ್ಕೆ ಬರುವ ವಸ್ತು\n\nಪಾವನವಾಗುತ್ತದೆ. ಅಗ್ನಿಯಲ್ಲಿದ್ದು ಅಗ್ನಿಗೆ ಇಂತಹ ತೇಜಸ್ಸನ್ನು ಕೊಟ್ಟ ಭಗವಂತ ಜಗತ್ತನ್ನು ಪಾವನಗೊಳಿಸುವ\nಪಾವಕಃ. ಎಲ್ಲರನ್ನು ಪಾವನಗೊಳಿಸುವ ಭಗವಂತ ದೇವತೆಗಳಿಗೂ ಕೂಡಾ ಅವಕ(ರಕ್ಷಕ).\n\nವಿತ್ತೇಶ ಕುಬೇರನ ಬಗ್ಗೆ ಹೇಳಿದ ಕೃಷ್ಣ ಮುಂದೆ ಭೂಮಿಯಲ್ಲಿ ಸಂಪತ್ತಿನ ನೆಲೆಯಾದ ಮೇರು ಪರ್ವಶದಲ್ಲಿ ತನ್ನ\nವಿಭೂತಿಯನ್ನು ವಿವರಿಸುತ್ತಾನೆ. ಮೇರು ಪರ್ವತವನ್ನು ಹೇಮಾದ್ರೀಚಿನ್ನದ ಬೆಟ್ಟ) ಎಂದು ಕರೆಯುತ್ತಾರೆ. ಅದು\nವಸುಗಳ ನೆಲೆ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಬೆಟ್ಟಗಳಲ್ಲಿ ಮೇರು ನಾನು” ಎಂದು. ಹಿಮಾಲಯದಲ್ಲಿನ ಪರ್ವತ\nಶ್ರೇಣಿಯಲ್ಲಿರುವ, ಮನುಷ್ಯ ಮಾತ್ರಕ್ಕೆ ಗೊತ್ತಿರದ ಸಂಪತ್ತಿನ ಬಗ್ಗೆ ಸ್ವಾಮಿರಾಮ್‌ ಅವರು ಪುಸ್ತಕದಲ್ಲಿ ತಮ್ಮ ಸ್ವಂತ ಅನುಭವವನ್ನು ಹಂಚಿಕೊಂಡಿದ್ದಾರೆ. ಯುದ್ಧದಲ್ಲಿ\nಪೂರ್ಣ ಸಂಪತ್ತು ನಾಶವಾದಾಗ ಧರ್ಮರಾಯ ಬೆಟ್ಟಗಳ ಸಾಲಿನಲ್ಲಿ ಹುದುಗಿಟ್ಟ ಸಂಪತ್ತನ್ನು ತರಿಸಿ ಯಜ್ಞ\nಮಾಡಿದ ಎಂದು ಮಹಾಭಾರತದಲ್ಲಿ ಹೇಳುತ್ತಾರೆ. ಈ ವಿಚಾರ ಹಿಮಾಲಯದಲ್ಲಿ ತಪಸ್ಸು ಮಾಡುವ ಕೆಲವು\nಯೋಗಿಗಳಿಗೂ ತಿಳಿದಿದೆ. ಇಂತಹ ಸಂಪತ್ತಿನ ನೆಲೆ ಮೇರು.\n\nಇಲ್ಲಿ ಬಂದಿರುವ ಭಗವಂತನ ವಿಭೂತಿನಾಮ 'ಮೇರುಃ. ಮಾ-ಈರು-ಮೇರು. ಸಮಸ್ತ ಚೈತನ್ಯದಲ್ಲಿ ಸರ್ವ\nಶ್ರೇಷ್ಠಳಾದ ತಾಯಿ ಮಹಾಲಕ್ಷ್ಮಿಗೂ ಸಹ ಪ್ರೇರಕನಾಗಿ ನಿಂತಿರುವವ ಭಗವಂತ. ಇಂತಹ ಭಗವಂತನಿಗೆ\nಇನ್ನೊಬ್ಬ ಪ್ರೆರಕನಿಲ್ಲ. ಆದ್ದರಿಂದ “ಮೇರುಃ” ಭಗವಂತನ ಅನ್ವರ್ಥನಾಮ.\n",
  "10.24": "ಪುರೋಧಸಾಮ್‌ ಚ ಮುಖ್ಯಮ್‌ ಮಾಮ್‌ ವಿದ್ಧಿ ಪಾರ್ಥ ಬೃಹಸ್ಪತಿಮ್‌ ।\n\nಸೇನಾನೀನಾಮ್‌ ಅಹಮ್‌ ಸ್ಕಂದಃ ಸರಸಾಮ್‌ ಅಸ್ಮಿ ಸಾಗರಃ -- ಓ ಪಾರ್ಥಾ, ಪುರೋಹಿತರಲ್ಲಿ ಹಿರಿಯನಾದ\nಬೃಹಸ್ಪತಿ ನಾನು.[ಬೃಹತ್‌-ಹಿರಿಯರಿಗೂ, ಪತಿ-ಒಡೆಯನಾಗಿ “ಬೃಹಸ್ಟತಿ'ಯಲ್ಲಿದ್ದೇನೆ.] ದಳವಾಯಿಗಳಲ್ಲಿ\nಸ್ಮಂದ ನಾನು.[ಅರಿಗಳ ಬೀರವನ್ನು ಹೀರಿ 'ಸ್ಮಂದ' ಎನ್ನಿ ಸಿ ನಾನು ಸೇನಾಪತಿ \"ಸ್ಕಂದ'ನಲ್ಲಿದ್ದೇನೆ.]\nನೀರಾಸರೆಗಳಲ್ಲಿ ಕಡಲು ನಾನು. [ಸಾ:ಸಾರವನ್ನು ಗರ-ಉಣ್ಣುವುದರಿಂದ, 'ಸಾಗರ' ಎನ್ನಿ ಸಿ ಕಡಲಿನಲ್ಲಿದ್ದೇನೆ.]\n\nನಾವು ಪೂಜಿಸುವ ಭಗವಂತನ ಪ್ರತೀಕವನ್ನು ಹೇಳಿದಮೇಲೆ ಎಲ್ಲವುದಕ್ಕೂ ಮುಖ್ಯವಾಗಿ ಬೇಕಾಗಿರುವ\nಪುರೋಹಿತರ ಬಗ್ಗೆ ಇಲ್ಲಿ ಹೇಳಲಾಗಿದೆ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ಪುರೋಹಿತರಲ್ಲಿ ನನ್ನ ಸನ್ನಿಧಾನವಿದೆ” ಎಂದು.\nಋಗ್ವೇದದ ಪ್ರಥಮ ಸೂಕ್ತದಲ್ಲಿ ಹೇಳುವಂತೆ: \" ಅಗ್ನಿಮೀ”ಳೇ ಪುರೋಹಿತಂ ಯಜ್ಞಸ್ಯ ದೇವಮೃತ್ವಿಜಂ” |\nಹೋತಾ”ರಂ ರತ್ನ ಧಾತಮಂ |\". ಇಲ್ಲಿ ಹೇಳುವ “ಹೋತಾ' ಋಗ್ವೇದದ ಪುರೋಹಿತ. ಹಿಂದೆ ಒಂದು ಯಾಗ\nಮಾಡುವಾಗ ಅಲ್ಲಿ ಹದಿನಾರು ಮಂದಿ ಪುರೋಹಿತರಿರುತ್ತಿದ್ದರು. ಋಗ್ವೇದಕ್ಕೆ: 'ಹೋತಾ' ಪ್ರಧಾನ ಮತ್ತು\nಆತನಿಗೆ ಮೂರು ಮಂದಿ(ಮೈತ್ರಾವರುಣ, ಅಚ್ಛಾವಾಕ, ಗ್ರಾಮಸ್ತುತ್‌) ಸಹಾಯಕರು. ಯಜುರ್ವೇದಕ್ಕೆ:\nಅಧ್ವರ್ಯು ಪ್ರಧಾನ ಮತ್ತು ಆತನಿಗೆ ಮೂರು ಮಂದೀಪ್ರತಿಪ್ರಸ್ಥುತಾ, ನೇಷ್ಟಾ, ಉನ್ನೇತಾ) ಸಹಾಯಕರು.\nಸಾಮವೇದಕ್ಕೆ: ಉದ್ಗಾತಾ ಪ್ರಧಾನ ಮತ್ತು ಆತನಿಗೆ ಮೂರು ಮಂದೀಪ್ರಸ್ತೋತಾ, ಪ್ರತಿಹರ್ತಾ, ಸುಬ್ರಹ್ಮಣ್ಯ)\n\nಸಹಾಯಕರು. ಈ ಎಲ್ಲರ ಮೇಲ್ವಿಚಾರಕರಾಗಿ, ಯಜ್ಞದಲ್ಲಿ ಯಾವುದೇ ಲೋಪದೋಷ ಬರದಂತೆ\nನೋಡಿಕೊಳ್ಳುವವರು ಸರ್ವವೇದ ಪಾರಂಗತ ಪ್ರಧಾನ ಪುರೋಹಿತರು. ಅವರಿಗೆ “ಬ್ರಹ್ಮಾ' ಎಂದು ಹೆಸರು.\nಇವರಿಗೂ ಮೂರು ಮಂದೀ(ಬ್ರಾಹ್ಮಾಣಾಇಚ್ಛಂಸಿ, ಅಗ್ನಿ ೇೀಧ್ರ, ಪೋತಾ) ಸಹಾಯಕರು. ಹೀಗೆ ಭಗವಂತನ ವಿಶೇಷ\nಸನ್ನಿಧಾನವಿರುವ ಹದಿನಾರು ಮಂದಿ ಪುರೋಹಿತರು ಸೇರಿ ಯಜ್ಞ ನೆರವೇರಿಸುತ್ತಿದ್ದರು. ಪುರೋಹಿತರ ಸ್ಥಾನ\nಸಮಾಜದಲ್ಲಿ ಅತ್ಯಂತ ಹಿರಿದು. ಆದರೆ ಇಂದಿನ ಪುರೋಹಿತರು ಹಿಂದಿನಷ್ಟು ಸ್ಥಾನಮಾನವನ್ನು ಸಮಾಜದಲ್ಲಿ\nಗಳಿಸುತ್ತಿಲ್ಲ. ಪುರೋಹಿತರು ನಮಗೆ ಹಿತವಾದದ್ದನ್ನು ನಮ್ಮಿಂದ ಮೊದಲೇ ತಿಳಿದು ನಮ್ಮನ್ನು ತಿದ್ದಿ ಆ ದಾರಿಯಲ್ಲಿ\nನಡೆಯುವಂತೆ ಮಾರ್ಗದರ್ಶನ ಮಾಡುವವರು. ನಮ್ಮ ಅಭಿವೃದ್ಧಿಗೆ ಪೂರಕವಾಗಿರತಕ್ಕಂತಹ ಕ್ರಿಯೆಗಳನ್ನು\nಮಾಡಿ ನಾವು ಅಭಿವೃದ್ಧಿಹೊಂದುವಂತೆ ಮುಂಜಾಗ್ರತೆ ಕೊಡುವ ಗುರುಸ್ಥಾನದಲ್ಲಿರುವ ಸಲಹೆಗಾರರು. ಇಡೀ\nಸಮಾಜಕ್ಕೆ ಇವರು ಮಾರ್ಗದರ್ಶಕರು. ಪೌರೋಹಿತ್ಯ ಬಹಳ ಜವಾಬ್ದಾರಿಯುತ ಕೆಲಸ. ಒಂದು ಧಾರ್ಮಿಕ\nನಡೆಯಲ್ಲಿ ಸಂಶಯಬಂದಾಗ ಸಮಾಜಕ್ಕೆ ಮಾರ್ಗದರ್ಶಿಯಾಗಿ ಕೆಲಸ ಮಾಡುವ ಪುರೋಹಿತನ ಜವಾಬ್ದಾರಿ\nಬಹಳ ದೊಡ್ಡದು. ಮಂತ್ರ ಹೇಳುವಾಗ ಯಾವುದಾದರು ಲೋಪವಾದರೆ, ತಪ್ಪು ಮಾಡಿದರೆ, ಅದಕ್ಕೆ ಪುರೋಹಿತ\nಕಾರಣನಾಗುತ್ತಾನೆ. ಇಂತಹ ಜವಾಬ್ದಾರಿಯುತ ಕೆಲಸ ಪೌರೋಹಿತ್ಯ. ಆದ್ದರಿಂದ ಭಗವಂತನ ವಿಶೇಷ\nಸನ್ನಿಧಾನ ಅಲ್ಲಿದೆ. ಭೂಮಿಯ ಎಲ್ಲಾ ಪುರೋಹಿತರಿಗಿಂತ ದೊಡ್ಡ ಪುರೋಹಿತರು ಇಬ್ಬರು. ದೈತ್ಯ\nಪುರೋಹಿತರಾದ ಶುಕ್ರಾಚಾರ್ಯರು ಮತ್ತು ದೇವತೆಗಳ ಪುರೋಹಿತರಾದ ಬೃಹಸ್ಪತಿಯಾಚಾರ್ಯರು.\nಬೃಹಸ್ಪತಿ ದೇವತಾ ತಾರತಮ್ಯದಲ್ಲಿ ಹತ್ತನೇ ಕಕ್ಷೆಯಲ್ಲಿದ್ದಾರೆ. ಇವರು ದೇವಲೋಕದಲ್ಲಿ ದೇವತೆಗಳಿಗೆ ಮತ್ತು\nದೇವೇಂದ್ರನಿಗೆ ಸಲಹೆಗಾರರು. ದೇವತೆಗಳಿಗೆ. ಪುರೋಹಿತರಾಗಿರುವ ಇವರಲ್ಲಿ ಭಗವಂತನ ವಿಶೇಷ\nಸನ್ನಿಧಾನವಿದೆ. ದೇವತಾ ತಾರತಮ್ಯದಲ್ಲಿ ಎಂಟನೇ ಕಕ್ಷೆಯಲ್ಲಿರುವ ಇಂದ್ರ ಹತ್ತನೇ ಕಕ್ಷೆಯಲ್ಲಿರುವ\nಬೃಹಸ್ಪತಿಯಾಚಾರ್ಯರಿಗೆ ನಮಸ್ಕರಿಸಿ ಅವರ ಮಾರ್ಗದರ್ಶನದಂತೆ ನಡೆಯಲು ಅವರಲ್ಲಿರುವ ಭಗವಂತನ\nಸನ್ನಿಧಾನವೇ ಕಾರಣ. ಇದನ್ನು ನೆನಪಿಸುವಂತೆ ಕೃಷ್ಣ ದೇವೇಂದ್ರನ ಅವತಾರವಾದ ಅರ್ಜುನನನ್ನು ಇಲ್ಲಿ\n\"ಪಾರ್ಥಾ' ಎಂದು ಸಂಬೋಧಿಸಿದ್ದಾನೆ.\n\nಇನ್ನೊಂದು ಮುಖದಲ್ಲಿ ನೋಡಿದರೆ ವೇದಗಳಲ್ಲಿ ಬೃಹಸ್ಪತಿ ಎಂದರೆ ಪ್ರಾಣದೇವರು. ಸರಸ್ವತಿ ಭಾರತಿಯರ\nಪತಿ-ಬೃಹಸ್ಪತಿಗಳು. ಇವರೇ ಬ್ರಹ್ಮ-ವಾಯು. ಇವರು ಸಮಸ್ತ ದೇವತೆಗಳಿಗೂ ಪುರೋಹಿತರು. ಭಗವಂತ\nಪ್ರಾಣದೇವರಲ್ಲಿ ಗಾನದ(ಕಂಠಸಿರಿ) ವಿಶೇಷ ವಿಭೂತಿಯಾಗಿ ನೆಲೆಸಿದ್ದಾನೆ.\n\nಇಲ್ಲಿ ಬಂದಿರುವ ಭಗವಂತನ ವಿಭೂತಿನಾಮ “ಬೃಹಸ್ಪತಿ'. ಬೃಹತ್‌ ಅಂದರೆ ಹಿರಿಯರು, ಪತಿ ಅಂದರೆ ಒಡೆಯ.\nಬ್ರಹ್ಮಾದಿ ಸಕಲ ದೇವತೆಗಳಿಗೂ ಒಡೆಯನಾದ, ಪುರೋಹಿತರಿಗೂ ಪುರೋಹಿತ ಭಗವಂತ “ಬೃಹಸ್ಪತಿ”.\nಅಧ್ಯಾತ್ಮ ಯೋಧರಾದ ಪುರೋಹಿತರ ಬಗ್ಗೆ ಹೇಳಿದ ಕೃಷ್ಣ, ಈಗ ಯುದ್ಧದಲ್ಲಿ ವಿಜಯ ತಂದುಕೊಟ್ಟು ರಕ್ಷಣೆ\nಮಾಡುವ ಯೋಧರಲ್ಲಿ ತನ್ನ ವಿಶೇಷ ವಿಭೂತಿಯನ್ನು ವಿವರಿಸುತ್ತಾನೆ. ದೇವತೆಗಳು ಬೃಹಸ್ಪತಿಯಾಚಾರ್ಯರ\nಮಾರ್ಗದರ್ಶನದಲ್ಲಿ ಸಂಪಾದಿಸಿದ ಸಂಪತ್ತನ್ನು ಅಸುರರು ಅಪಹರಿಸಿದಾಗ, ಅವರ ವಿರುದ್ಧ ಹೋರಾಡಿ ಅದನ್ನು\nಹಿಂದಕ್ಕೆ ತಂದುಕೊಟ್ಟವ ಸ್ಕಂದಃ. ಭಗವಂತ “ಸ್ಕಂದಃ ನಾಮಕನಾಗಿ ಸೇನಾನಿಯಲ್ಲಿ ನಿಂತು ನಡೆಸುತ್ತಾನೆ.\nಸ್ಕಂದನಿಗೆ ಸೇನಾಧಿಪತಿಯಾಗಿ ತಾರಕಾಸುರನನ್ನು ಸಂಹಾರ ಮಾಡುವಂತಹ ಶಕ್ತಿ ಕೊಟ್ಟಂತಹ, ಅಂತರಂಗದ\nಒಳಗೆ ಕುಳಿತ ಅಂತರ್ಯಾಮಿ ತತ್ವ-ಭಗವಂತ. ಸೇನಾನಿಯ ಬಗ್ಗೆ ಹೇಳುವಾಗ ಇಲ್ಲಿ ಸೇನಾನಿಯಾಗಿ ಕೀರ್ತಿ\n\nಪಡೆದ ಕರ್ನಾಟಕದ ಹೆಮ್ಮೆಯ ಪುತ್ರ “ಕಾರ್ಯಪ್ಪ” ಅವರನ್ನು ನೆನೆಸಿಕೊಳ್ಳಬಹುದು. ಭಗವಂತನ ವಿಶೇಷ\nಸನ್ನಿದಾನದಿಂದಾಗಿ ಸೇನಾಧಿಪತಿಯಲ್ಲಿ ಅಂತಹ ವಿಶೇಷ ಶಕ್ತಿ ಬರುತ್ತದೆ.\n\nಇಲ್ಲಿ ಬಂದಿರುವ ಭಗವಂತನ ವಿಭೂತಿನಾಮ ಸ್ಕಂದಃ. 'ಸ್ಮಂದಃ' ಎಂದರೆ ಇಡೀ ಜಗತ್ತನ್ನು ಸಂಹಾರ ಮಾಡುವ\nಶಕ್ತಿ. “ಅರಿಗಳ ಬೀರವನ್ನು ಹೀರಿ 'ಸ್ಕಂದ' ಎನ್ನಿಸಿ ನಾನು ಸೇನಾಪತಿ “ಸ್ಮಂದ'ನಲ್ಲಿದ್ದೇನೆ” ಎಂದಿದ್ದಾನೆ ಕೃಷ್ಣ.\nಮುಂದುವರಿದು ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಸರಸಾಮಸ್ಮಿ ಸಾಗರಃ” ಎಂದು. ಭೂಮಿಯ ಮೇಲಿನ ಅಪಾರ ಸಂಪತ್ತಿನ\nತಾಣ ಮೇರು ಪರ್ವತವಾದರೆ, ರಸದಿಂದ ಸಹಿತವಾದ, ಜಲಾಶಯಗಳಲ್ಲಿ ಬಹಳ ದೊಡ್ಡದಾಗಿರುವುದು ಸಾಗರ.\n“ಅದರಲ್ಲಿ ವಿಭೂತಿಯಾಗಿ ನಾನಿದ್ದೇನೆ” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಭೂಮಿಯ ಯಾವಭಾಗದಲ್ಲಿ ಬಾವಿ ತೋಡಿದರೂ\nಸಿಹಿ ನೀರು. ಆದರೆ ಅಪರಂಪಾರವಾದ ಸಾಗರದ ನೀರು ಉಪ್ಪು. ಇದು ಏಕೆ ಎಂದು ನಮಗೆ ಗೊತ್ತಿಲ್ಲ. ರಷ್ಯಾದ\nವಿಖ್ಯಾತ ಮನಃಶಾಸ್ತ್ರಜ್ಞ ವಿಲಿಕೋ\"ಸ್ಕಿ (Velikovsky)/) ತನ್ನ \"Worlds in Collision\" ಎನ್ನುವ ಪುಸ್ತಕದಲ್ಲಿ\nಹೇಳುತ್ತಾನೆ: “ನಾವು ವಿಶ್ವದ ವಿಸ್ಮಯವನ್ನೆಲ್ಲಾ ಭೇದಿಸಿದ ಭ್ರಮೆಯಲ್ಲಿದ್ದೇವೆ, ಆದರೆ ನಮಗೆ ಏನೂ ಗೊತ್ತಿಲ್ಲ”\nಎಂದು. ಇಂದು ಸಮುದ್ರದ ನೀರು ಉಪ್ಪು ಏಕೆ, ಬಾವಿಯ ನೀರು ಸಿಹಿ ಏಕೆ ಎನ್ನುವುದೂ ನಮಗೆ ಗೊತ್ತಿಲ್ಲ.\nಭಗವಂತ ಇತರ ಎಲ್ಲಾ ರಸವನ್ನು ಹಣ್ಣಿನಲ್ಲಿಟ್ಟ. ಆದರೆ ರಸದ-ರಸ ಲವಣರಸ ಉಪ್ಪನ್ನು ಮಾತ್ರ ಯಾವ\nಹಣ್ಣಿನಲ್ಲೂ ಇಡದೆ-ಸಮುದ್ರದ ನೀರಿನಲ್ಲಿಟ್ಟ. ಈ ಸಮುದ್ರ ಒಂದು ವಿಸ್ಮಯ. ಭೂಮಿ ಮೇಲಿನ ಪ್ರಾಣಿ\nವೈವಿದ್ಯಕ್ಕಿಂತ ಹೆಚ್ಚು ವೈವಿದ್ಯ ಸಮುದ್ರದಲ್ಲಿದೆ. ಭಗವಂತ ಸಮುದ್ರವನ್ನು ಸೃಷ್ಟಿ ಮಾಡಿ ಅದರಲ್ಲಿ ಸಾಗರಃ\nಶಬ್ದವಾಚ್ಯನಾಗಿ ತುಂಬಿದ್ದಾನೆ.\n\nಇಲ್ಲಿ ಬಂದಿರುವ ಭಗವಂತನ ವಿಭೂತಿನಾಮ ಸಾಗರಃ. ಸಾರ-ಗರ-ಸಾಗರ. ಸಾರವಾಗಿರುವುದನ್ನು\nಸ್ವೀಕರಿಸುವ ಭಗವಂತ ಸಾರಃ. ಎಲ್ಲಕ್ಕೆಂತ ಮಹತ್ತಾದ ಸಾರ-ಲವಣ, ಅದರಲ್ಲಿ ತುಂಬಿರುವ ಭಗವಂತ ಸಾಗರಃ.\nಸಾರಂ ಗರತಿ ದದಾತೀತಿ ಸಾಗರಃ. ಜಗತ್ತಿಗೆ ಜೀವನದ ಸಾರ ಸರ್ವಸ್ವವನ್ನು ಕೊಡುವ ಭಗವಂತ ಸಾಗರಃ.\n\nಮಹರ್ಷೀಣಾಂ ಭೃಗುರಹಂ ಗಿರಾಮಸ್ಮೆ ಚಕಮಕ್ಷರಮ್‌ |\n\nಯಜ್ಞಾನಾಂ ಜಪಯಜ್ಞೋಷ",
  "10.25": "ಮಹರ್ಷೀಣಾಮ್‌ ಭೃಗುಃ ಅಹಮ್‌ ಗಿರಾಮ್‌ ಅಸ್ಮಿ ಏಕಮ್‌ ಅಕ್ಷರಮ್‌।\n\nಯಜ್ಞಾನಾಮ್‌ ಜಪಯಜ್ಞಃ ಅಸ್ಮಿ ಸ್ಥಾವರಾಣಾಮ್‌ ಹಿಮಾಲಯ; -ಮಹರ್ಷಿಗಳಲ್ಲಿ ಭೃಗು ನಾನು. [ಕೆಟ್ಟವರನ್ನು\nಸುಟ್ಟುರಿದು, “ಭೃಗು' ಎನ್ನಿಸಿ, “ಭೃಗು'ಮುನಿಯಲ್ಲಿದ್ದೇನೆ.] ವಾಜ್ಮಯಗಳಲ್ಲಿ ಓಂಕಾರವೆಂಬ ಒಂದಕ್ಷರ ನಾನು.\n[ಎಲ್ಲಕ್ಕಿಂತ ಮಿಗಿಲಾಗಿ 'ಏಕ' ಎನ್ನಿಸಿ, ಅಳಿವಿರದ್ದರಿಂದ “ಅಕ್ಷರ' ಎನ್ನಿ ಸಿ ಓಂಕಾರವಾಚ್ಯನಾಗಿದ್ದೇನೆ.] ಯಜ್ಞಗಳಲ್ಲಿ\n\n1\n\nಜಪಯಜ್ಞ ನಾನು.[ಜಹುಟ್ಟಿದ್ದನ್ನೆಲ್ಲಾ, ಪಾಪಾಲಿಸುವುದರಿಂದ 'ಜಪ'ಎನ್ನಿಸಿ, ಎಲ್ಲರ ಎಲ್ಲಾ ಪೂಜೆಗಳನ್ನು\n\n೦ 0 ೧ಣ\n\nಕೊಳ್ಳುವುದರಿಂದ 'ಯಜ್ಞ'ಎನ್ನಿಸಿ. ಜಪಯಜ್ಞದಲ್ಲಿದ್ದೇನೆ.] ಘನವಾದ ಬೆಟ್ಟಗಳಲ್ಲಿ ಹಿಮಾಲಯ ನಾನು.\n\n[ಪ್ರೀಏಲಕ್ಷ್ಮಿಯ 'ಹ್ರೀ'ಸಾಮಕ ರೂಪಕ್ಕೆ ಮತ್ತು ಮಾಃಶ್ರೀ' ನಾಮಕ ರೂಪಕ್ಕೆ ಆಲಯನೆಲೆಯಾದ್ದರಿಂದ\n'ಹಿಮಾಲಯ' ಎನ್ನಿಸಿ ಹಿಮಗಿರಿಯಲ್ಲಿದ್ದೇನೆ.]\n\nಈ ಹಿಂದೆ ನಾವು ದೇವರ್ಷಿ ಬೃಹಸ್ಪತಿಯ ಬಗ್ಗೆ ನೋಡಿದೆವು. ಇವರು ದೇವಲೋಕಕ್ಕೆ ಸಂಬಂಧಪಟ್ಟವರು.\nಇವರನ್ನು ಬಿಟ್ಟು ಇತರ ಮಹರ್ಷಿಗಳನ್ನು ನೋಡಿದರೆ-ಭಗವಂತನನ್ನು ಕಂಡ ವಿಶಿಷ್ಟರಲ್ಲಿ ಅತ್ಯಂತ\nಶ್ರೇಷ್ಠರಾದವರು. ಭೃಗು ಮಹರ್ಷಿಗಳು. ವಿಶ್ವಾಮಿತ್ರ-ವಸಿಷ್ಠರು. ತಾರತಮ್ಯ ಕಕ್ಷೆಯಲ್ಲಿ ಹದಿನಾರನೇ\nಸ್ಥಾನದಲ್ಲಿದ್ದರೆ, ಭೃಗುಮುನಿಗಳು ಇವರಿಂದ ಎತ್ತರದಲ್ಲಿ ಹದಿನೈದನೇ ಕಕ್ಷೆಯಲ್ಲಿ ಅಗ್ನಿಗೆ ಸಮಾನರಾಗಿದ್ದಾರೆ.\nಇವರು ಭೂಮಿಯಲ್ಲಿ ಖುಷಿಗಳ ಮಾಲಿಕೆಯಲ್ಲಿ ಹೊಸ ಆವಿಷ್ಕಾರ ಮಾಡಿದವರು. ಭಾಗವತದಲ್ಲಿ ಬರುವ ಒಂದು\nಕಥೆಯಂತೆ ತ್ರಿಮೂರ್ತಿಗಳಲ್ಲಿ ಯಾರು ಅತ್ಯಂತ ಶ್ರೇಷ್ಠರು ಎಂದು ಅಳೆಯುವ ನಿಯೋಗಶ್ರೇಷ್ಠರಾಗಿ ಹೋಗಿ,\n“ನಾರಾಯಣ' ಸರ್ವ ಶ್ರೇಷ್ಠ ಎಂದು ಜಗತ್ತಿಗೆ ಸಾರಿದ ಬಹಳ ದೊಡ್ಡ ಮುನಿ ಭೃಗು. ಈ ಕಥೆಯಲ್ಲಿ ಹೇಳುವಂತೆ-\nನಿಯೋಗ ಶ್ರೇಷ್ಠರಾಗಿ ಭೃಗು ಮೊದಲು ಶಿವನಲ್ಲಿಗೆ, ನಂತರ ಬ್ರಹ್ಮನಲ್ಲಿಗೆ ಹೋಗುತ್ತಾರೆ. ಅಲ್ಲಿ ಅವರಿಗೆ ಯಾವ\nಪುರಸ್ಕಾರವೂ ದೊರೆಯದಿದ್ದಾಗ, ಭೃಗು ಸಿಟ್ಟಿನಿಂದಲೇ ನಾರಾಯಣನಲ್ಲಿಗೆ ಹೋಗುತ್ತಾರೆ. ಅಲ್ಲಿ ವಿಷ್ಣು ಕೂಡಾ\nಇವರನ್ನು ಗಮನಿಸದೇ ಇದ್ದಾಗ, ಸಿಟ್ಟಿನಿಂದ ವಿಷ್ಣುವಿನ ಎದೆಗೆ ಒದೆಯುತ್ತಾರೆ. ಆಗ ಭಕ್ತವತ್ಸಲ ನಾರಾಯಣ:\n“ನೀವು ಕರೆದಿದ್ದರೆ ನಾನು ಬರುತ್ತಿದ್ದೆ, ಈ ರೀತಿ ಒದೆದುದರಿಂದ ನಿಮ್ಮ ಕಾಲಿಗೆ ಅದೆಷ್ಟು ನೋವಾಯಿತೋ”\nಎಂದು ಅವರ ಕಾಲನ್ನು ಉಜ್ಜಲು ಆರಂಭಿಸುತ್ತಾನೆ. ಆಗ ಭೃಗು ತನ್ನ ತಪ್ಪನ್ನು ಅರಿತು ನಾರಾಯಣನಲ್ಲಿ\nಶರಣಾಗುತ್ತಾರೆ. ಈ ಕಥೆಯನ್ನು ನೋಡಿದಾಗ ನಮಗೆ ಈ ಮುನಿಗಳಿಗೆ ಭಗವಂತನ ಮಹತ್ವ ಗೊತ್ತಿರಲಿಲ್ಲವೇ\nಎನ್ನುವ ಪ್ರಶ್ನೆ ಮೂಡುತ್ತದೆ. ಖಂಡಿತವಾಗಿ ಅವರಿಗೆ ಭಗವಂತನ ಪೂರ್ಣ ಮಹತ್ವ ತಿಳಿದಿತ್ತು. ಇದು ಕೇವಲ\nಜನಸಾಮಾನ್ಯರಿಗೆ ಕ್ರಿಯೆಯ ಮೂಲಕ ವಿಷಯನ್ನು ತಿಳಿಸುವ ಒಂದು ಕಾರ್ಯ ಅಷ್ಟೆ. ಇದೇ ರೀತಿ “ನೀನು\nಭೂಮಿಯ ಮೇಲೆ ಹತ್ತು ಬಾರಿ ಅವತಾರ ತಾಳು” ಎಂದು ಭಗವಂತನಿಗೆ ಶಾಪ ಕೊಟ್ಟವರು ಭೃಗು. ಅವರ\nಶಾಪಕ್ಕೆ ಪುರಸ್ಕಾರ ಕೊಡುವುದಕ್ಕೆ ಭಗವಂತ ಭೂಮಿಯ ಮೇಲೆ ಹತ್ತು ಅವತಾರ ತಾಳಿದ. ಲಕ್ಷ್ಮಿ\nಭಾರ್ಗವಿಯಾಗಿ ಭೃಗು ಮುನಿಯಲ್ಲಿ ಮಗಳಾಗಿ ಹುಟ್ಟಿದಳು. ಈ ರೀತಿ ಭೃಗುವಿನಲ್ಲಿ ಅನೇಕ ವೈಶಿಷ್ಟ್ಯವನ್ನು\nಕಾಣುತ್ತೇವೆ. ಇದಕ್ಕೆಲ್ಲ ಕಾರಣ ಭೃಗುವಿನಲ್ಲಿ ಭಗವಂತನ ವಿಶೇಷ ಸನ್ನಿ ದಾನ.\n\nಇಲ್ಲಿ ಬಂದಿರುವ ಭಗವಂತನ ವಿಭೂತಿನಾಮ 'ಭೃಗುಃ'. ಭರ್ಜನಾತ್‌ ಇತಿ ಭೃಗುಃ. ಪ್ರಳಯ ಕಾಲದಲ್ಲಿ ಎಲ್ಲವನ್ನೂ\nಭರ್ಜನೆ ಮಾಡುವ ಭಗವಂತ, ಮುಖ್ಯವಾಗಿ ಭಕ್ತರ ಪಾಪವನ್ನು ಭರ್ಜನೆ(ನಾಶ)ಮಾಡುವ ಭೃಗುಃ. ಭಗವಂತ\nತನ್ನ ಭಕ್ತರ ಜೀವನದಲ್ಲಿ ಅಡ್ಡಿ ಮಾಡುವ ದುಷ್ಟ ಶಕ್ತಿಗಳನ್ನು ಭರ್ಜನೆ ಮಾಡುವವ. ದುಷ್ಟರನ್ನು ಮತ್ತು\nಅಧರ್ಮವನ್ನು ಭರ್ಜನೆ ಮಾಡಿ, ಧರ್ಮ ಸಂಸ್ಥಾಪನೆ ಮಾಡುವ ಭಗವಂತ ಭೃಗುಃ ಶಬ್ದ ವಾಚ್ಯ. ಋಷಿಗಳಲ್ಲಿ\nಅತ್ಯಂತ ಎತ್ತರ ಸ್ಥಾನ ಭೃಗುವಿಗೆ ಬರುವಂತೆ ಮಾಡಿ, ಅವರಲ್ಲಿ ಭೃಗು ಶಬ್ದ ವಾಚ್ಯನಾಗಿ ಭಗವಂತ\nಸನ್ನಿಹಿತನಾಗಿದ್ದಾನೆ.\n\nಋಷಿಗಳ ಬಗ್ಗೆ ಹೇಳಿದಾಗ ಖುಷಿಗಳು ಭಗವಂತನಿಗೆ ಹತ್ತಿರ ಹೇಗಾದರು ಎನ್ನುವ ಪ್ರಶ್ನೆ ನಮ್ಮಲ್ಲಿ ಮೂಡುತ್ತದೆ.\nಇದಕ್ಕೆ ಕಾರಣ- ಉಪಾಸನೆ, ಮಂತ್ರ-ಜಪ ಸಿದ್ಧಿ. ಕ್ಷತ್ರಿಯನಾದ ವಿಶ್ವಾಮಿತ್ರ ಕೂಡಾ ವೇದಮಂತ್ರ ಜಪ\nಸಿದ್ಧಿಯಿಂದ ಬ್ರಹ್ಮರ್ಷಿಯಾದ. ಖುಷಿಯಾಗಬೇಕಿದ್ದರೆ, ಋಷಿತ್ವ ಪಡೆಯಬೇಕಿದ್ದರೆ ಓಂಕಾರದ ಉಪಾಸನೆಯಿಂದ\nಭಗವಂತನನ್ನು ಸಾಕ್ಷಾತ್ಕಾರಗಳಿಸಿಕೊಳ್ಳಬೇಕು. ಪ್ರಪಂಚದಲ್ಲಿರುವ ಅತ್ಯಂತ ಮಹತ್ವವಾದ ಮತ್ತು ಶ್ರೇಷ್ಠ ಶಬ್ದ\nಓಂಕಾರ. ಈ ಓಂಕಾರದಲ್ಲಿ ಅಕ್ಷರಃ ನಾಮಕ ಭಗವಂತನ ವಿಶೇಷ ಸನ್ನಿದಾನವಿದೆ. ಓಂಕಾರ ಭಗವಂತನ\nವಿಶೇಷ(Exclusive name)ನಾಮ. [ಓಂಕಾರಕ್ಕೆ ಕೃಷ್ಣ ಇಷ್ಟು ಮಹತ್ವ ಏಕೆ ಕೊಟ್ಟ, ಓಂಕಾರದಲ್ಲಿರುವ ಅಸಾಧಾರಣ\n\nವೈಶಿಷ್ಟ್ಯ ಏನು ಎನ್ನುವುದರ ವಿಶೇಷ ಅರ್ಥ ವಿವರಣೆಯನ್ನು, ನಾವು ಏಳನೇ ಅಧ್ಯಾಯದಲ್ಲಿ ಈಗಾಗಲೇ\nನೋಡಿದ್ದೇವೆ(ಅ-೭, ಶ್ಲೋಕ-೮)]. ಎಂದೂ ನಾಶವಿಲ್ಲದ(ಅ-ಕ್ಷರ) ಭಗವಂತ ಎಲ್ಲರಿಗಿಂತ ಹಿರಿದಾದ ಏಕಮಾತ್ರ\nತತ್ವ. ಆದ್ದರಿಂದ ಆತ ಏಕಃ.\nಓಂಕಾರದ ನಂತರ ಇಲ್ಲಿ ಜಪಯಜ್ಞದ ಬಗ್ಗೆ ಕೃಷ್ಣ ವಿವರಿಸುತ್ತಾನೆ. “ಯಜ್ಞಾನಾಮ್‌ ಜಪಯಜ್ಞಃ ಅಸ್ಮಿ” ಎನ್ನುತ್ತಾನೆ\nಕೃಷ್ಣ. ಎಲ್ಲಕ್ಕಿಂತ ದೊಡ್ಡ ಯಜ್ಞ ಅಂದರೆ ಜಪಯಜ್ಞ. ಹಿಂದೆ ಹೇಳಿದಂತೆ ಅಗ್ನಿ ಮುಖದಲ್ಲಿ ಮಾಡುವ ಪೂಜೆ\nಮಾತ್ರ ಯಜ್ಞವಲ್ಲ. ಕೊಡುವಿಕೆ, ಪೂಜೆಯಂತಹ ಒಳ್ಳೆಯ ಕಾರ್ಯಕ್ಕೆ ಒಂದು ಕಡೆ ಸೇರುವಿಕೆ(ಸಂಗತೀಕರಣ),\nಜ್ಞಾನದಾನ, ಅನ್ನದಾನ, ನಮ್ಮಲ್ಲಿ ಹೆಚ್ಚಿಗೆ ಇರುವುದನ್ನು ಇಲ್ಲದವರಿಗೆ ಹಂಚಿ ಬದುಕುವುದು, ಎಲ್ಲವೂ ಒಂದು\nಯಜ್ಞವೇ. ಸಾಮಾನ್ಯವಾಗಿ ಯಜ್ಞದಲ್ಲಿ ಎರಡು ವಿಧ. ಒಂದು ಅಂತರಂಗ ಯಜ್ಞ ಇನ್ನೊಂದು ಬಾಹ್ಯಯಜ್ಞ.\nಅಂತರಂಗದಲ್ಲಿ. ಭಗವಂತನ ನಿರಂತರ ಪೂಜೆ(ದೇವಪೂಜಾ); ಚಿತ್ತ-ಮನಸ್ಸು ಭಗವಂತನ ಜೊತೆಗೆ\nಸೇರುವುದು(ಸಂಗತೀಕರಣ) ಮತ್ತು ನಮ್ಮನ್ನು ನಾವು ಭಗವಂತನಿಗೆ ಅರ್ಪಿಸಿಕೊಳ್ಳುವುದು-ಪರಿಪೂರ್ಣವಾದ\nಮಾನಸ ಯಜ್ಞ. ಈ ರೀತಿ ಮನಸ್ಸಿನಲ್ಲಿ ಮಾಡುವ ಜಪಯಜ್ಞ ಅತ್ಯಂತ ಶ್ರೇಷ್ಠ. ಇದಕ್ಕೆ ಕಾರಣ ಜಪಯಜ್ಞದಲ್ಲಿನ\nಭಗವಂತನ ವಿಭೂತಿ.\nಇಲ್ಲಿ ಬಂದಿರುವ ಭಗವಂತನ ವಿಭೂತಿನಾಮ 'ಜಪಃ' ಮತ್ತು 'ಯಜ್ಞಃ'. ಜಗತ್ತಿನಲ್ಲಿ ಹುಟ್ಟಿಬರುವ ಪ್ರತಿಯೊಂದು\nಜೀವವನ್ನು ಪಾಲಿಸುವ ಭಗವಂತ 'ಜಪಃ. ಇಂತಹ ಭಗವಂತ ಎಲ್ಲರ ಎಲ್ಲಾ ಪೂಜೆಗಳನ್ನು ಕೊಳ್ಳುವುದರಿಂದ\n\"ಯಜ್ಞ'ಎನ್ನಿಸಿ ಜಪಯಜ್ಞದಲ್ಲಿದ್ದಾನೆ.\nಜಪದ ಬಗ್ಗೆ ಹೇಳಿದ ಮೇಲೆ, ಭೂಮಿಯ ಮೇಲೆ ಸಾತ್ವಿಕ ಕಂಪನ ಇರುವ ಅತ್ಯಂತ ಶ್ರೇಷ್ಠ ಸ್ಥಾವರದ ಬಗ್ಗೆ ಕೃಷ್ಣ\nಹೇಳುತ್ತಾನೆ. ಹಿಂದೆ ಮನೆ ಕಟ್ಟುವಾಗ ಅಲ್ಲಿ ಹೆಚ್ಚು ಸಾತ್ವಿಕ ಕಂಪನ ಇರುವ ಸ್ಥಳದಲ್ಲಿ ದೇವರ ಕೋಣೆಯನ್ನು\nನಿರ್ಮಿಸುತ್ತಿದ್ದರು. ಒಂದು ಊರಿನಲ್ಲಿ ಅತಿ ಹೆಚ್ಚು ಸಾತ್ವಿಕ ಕಂಪನ ಇರುವ ಸ್ಥಳದಲ್ಲಿ ದೇವಸ್ಥಾನ\nನಿರ್ಮಿಸುತ್ತಿದ್ದರು. ಈ ಭೂಮಿಯಲ್ಲಿ ಅತಿ ಹೆಚ್ಚು ಸಾತ್ವಿಕ ಕಂಪನ ಇರುವ ಏಕ ಮಾತ್ರ ಸ್ಥಳ ಹಿಮಾಲಯ. ಇಲ್ಲಿ\nಎಲ್ಲಿ ಕುಳಿತರೂ ನಮ್ಮ ಮನಸ್ಸು ಬಹು ಸುಲಭದಲ್ಲಿ ಭಗವಂತನಲ್ಲಿ ಶ್ರುತಿಗೂಡುತ್ತದೆ. ಹಿಮಾಲಯಕ್ಕೆ ಈ ಶಕ್ತಿ\nಭಗವಂತನ ವಿಶೇಷ ಸನ್ನಿದಾನದಿಂದ ಬಂತು. ಭಗವಂತ 'ಹಿಮಾಲಯಃ' ನಾಮಕನಾಗಿ ಇಲ್ಲಿ ನೆಲೆಸಿದ್ದಾನೆ.\nಭಗವಂತನ ಈ ವಿಭೂತಿನಾಮಕ್ಕೆ ವಿಶೇಷ ಅರ್ಥವಿದೆ. ಹ್ರೀಮಾ-ಆಲಯ-ಹಿಮಾಲಯ. ಹ್ರೀ ಅಂದರೆ\nಶ್ರೀಲಕ್ಷ್ಮಿ, ಮಾ ಅಂದರೆ ಭೂದೇವಿ. ಶ್ರೀದೇವಿ ಮತ್ತು ಭೂದೇವಿಯರ ಆಲಯನಾದ ಭಗವಂತ ಹಿಮಾಲಯಃ.\nಭಗವಂತನ ಈ ವಿಶೇಷ ವಿಭೂತಿಯಿಂದಾಗಿ ಹಿಮಾಲಯದ ಕಣಕಣವೂ ಅಧ್ಯಾತ್ಮದ ವಿಸ್ಮಯದಿಂದ ತುಂಬಿದೆ.\nಮನುಷ್ಯನ ಮನಃಪರಿವರ್ತನೆ ಮಾಡಿ ಆತನನ್ನು ಅಧ್ಯಾತ್ಮದತ್ತ ತಿರುಗಿಸುವ ವಿಶೇಷಶಕ್ತಿ ಹಿಮಾಲಯಕ್ಕಿದೆ.\nವೇದವ್ಯಾಸರು, ನರ-ನಾರಾಯಣರು, ಆಚಾರ್ಯ ಮಧ್ವರು ನೆಲೆಸಿರುವ ತಾಣ ಹಿಮಾಲಯ. ಅನೇಕ\nದೇವತೆಗಳು ನೆಲೆಸಿರುವ ನಿಗೂಢ ತಾಣ ಈ ಹಿಮಾಲಯ. ಭಗವಂತನ ವಿಭೂತಿ ಈ ನೆಲಕ್ಕೆ ಈ ಅದ್ಭುತ\nಶಕ್ತಿಯನ್ನು ತಂದುಕೊಟ್ಟಿದೆ.\n",
  "10.26": "ಅಶ್ವತ್ಥಃ ಸರ್ವ ವೃಕ್ಷಾಣಾಮ್‌ ದೇವರ್ಷೀಣಾಮ್‌ ಚ ನಾರದಃ |\n\nಗಂಧರ್ವಾಣಾಮ್‌ ಚಿತ್ರರಥಃ ಸಿದ್ಧಾನಾಮ್‌ ಕಪಿಲಃ ಮುನಿಃ -ಎಲ್ಲಾ ಮರಗಳಲ್ಲಿ ಅರಳಿಮರ\nನಾನು.[ಅಶ್ವಂಕುದುರೆಯ ರೂಪದಲ್ಲಿ ಸ್ಥಂಇದ್ದುದರಿಂದ, “ಅಶ್ವತ್ಥ' ಎನಿಸಿ ಅರಳಿಮರದಲ್ಲಿದ್ದೇನೆ.] ದೇವಲೋಕದ\nಖುಶಿಗಳಲ್ಲಿ ನಾರದ ನಾನು. [ನಾರ:ನರರ ಬಯಕೆಯೆಲ್ಲವನ್ನು ದಕೊಡುವವನಾಗಿ “ನಾರದ' ಎನ್ನಿಸಿ\nನಾರದನಲ್ಲಿದ್ದೇನೆ.] ಗಂಧರ್ವರ ದೊರೆ ಚಿತ್ರರಥ ನಾನು. [ಚಿತ್ರ:-ಅಚ್ಚರಿಯ, ರಥ-ತೇರಿನಲ್ಲಿ ಚರಿಸುವುದರಿಂದ\n'ಚಿತ್ರರಥ'. ಎನ್ನಿಸಿ. ಗಂದರ್ವ ರಾಜ ಚಿತ್ರರಥನಲ್ಲಿದ್ದೇನೆ.] ಯೋಗಸಿದ್ಧರಲ್ಲಿ[ಕ-ಸುಖರೂಪನಾಗಿ,\nಪಿಂಪಾಲಿಸುವುದರಿಂದ, ಮತ್ತು ಲಂಲಯಗೊಳಿಸುವುದರಿಂದ] ಕಪಿಲ ಮುನಿ ನಾನು.\n\nಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಸರ್ವ ವೃಕ್ಷಗಳಲ್ಲಿ ಅಶ್ವತ್ಥ ನಾನು” ಎಂದು. ಅಶ್ವತ್ಸಮರ ಇಂದು ಮೇಲ್ನೋಟದಲ್ಲಿ\nನೋಡುವವರಿಗೆ ಯಾವುದಕ್ಕೂ ಉಪಯೋಗವಿಲ್ಲದ ಮರ. ಭಗವಂತ ಈ ಮರಕ್ಕೆ ಮಹತ್ವ ಕೊಟ್ಟು ಹೇಳದಿದ್ದರೆ\nಈ ಮರದ ಬಗ್ಗೆ ನಮಗೆ ಏನೂ ತಿಳಿದಿರುತ್ತಿರಲಿಲ್ಲ. ಏಕೆಂದರೆ ಈ ಮರ ನಮಗೆ ತಿನ್ನುವ ಹಣ್ಣನ್ನಾಗಲಿ,\nಸುಗಂಧವಾದ ಹೂವನ್ನಾಗಲೀ ಕೊಡುವುದಿಲ್ಲ. ಈ ಮರದಿಂದ ಪೀಠೊಪಕರಣ ಮಾಡಲು ಸಾಧ್ಯವಿಲ್ಲ.\nವಿಶಾಲವಾಗಿ ಬೆಳೆದು ತನ್ನ ಸುತ್ತಲಿನ ಪ್ರದೇಶವನ್ನು ಆಕ್ರಮಿಸಿ ನಿಲ್ಲುವ ಈ ಮರ, ಮೇಲ್ನೋಟಕ್ಕೆ ಜನರಿಗೆ ಕಾಟ\nಕೊಡುವ ಮರ! ಆದರೆ ಇಲ್ಲಿ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ವೃಕ್ಷಗಳ ಸಮುದಾಯದಲ್ಲಿ ಶ್ರೇಷ್ಠ ವೃಕ್ಷ ಅಶ್ವತ್ಥ” ಎಂದು. ಏಕೆ\nಈ ಮರಕ್ಕೆ ಇಷ್ಟು ಪ್ರಾಧಾನ್ಯತೆ ಎನ್ನು ವುದು ತಿಳಿಯದೇ ಇಂದು ನಾವು ಅದನ್ನು ಪೂಜಿಸುತ್ತೇವೆ ಅಥವಾ ಇನ್ನು\nಕೆಲವರು ನಿರ್ಲಕ್ಷಿಸುತ್ತಾರೆ. ಈ ಮರವನ್ನು ನೆಟ್ಟರೆ ಪುಣ್ಯಬರುತ್ತದೆ ಎನ್ನುವ ಕಾರಣಕ್ಕೆ ಮನೆಯಿಂದ ದೂರದಲ್ಲಿ\nಎಲ್ಲೋ ದೇವಸ್ಥಾನದಲ್ಲಿ ಅರಳಿ ಮರ ನೆಡುವುವವರಿದ್ದಾರೆ. ಇಂದು ಈ ಮರದ ಮಹತ್ವ ಹೆಚ್ಚಿನವರಿಗೆ ತಿಳಿದಿಲ್ಲ.\nಹಿಂದಿನವರು ಆಲ, ಅರಳಿ ಮತ್ತು ಅತ್ತಿ ಈ ಮೂರು ಮರಗಳಿಗೆ ಬಹಳ ಮಹತ್ವ ಕೊಟ್ಟರು. [ಬೇಂದ್ರೆಯವರು\nತಮ್ಮ ತೋಟದಲ್ಲಿ ಮೂಡಿಬಂದ ಈ ಮೂರು ಗಿಡಗಳನ್ನು ನೋಡಿ- “ನಮ್ಮ ತೋಟದಲ್ಲಿ ಭಗವಂತ ಮೂರು\nರೂಪದಲ್ಲಿ ಬಂದಿದ್ದಾನೆ” ಎಂದು ಹೃದಯತುಂಬಿ ಹೇಳಿದ್ದನ್ನು ಇಲ್ಲಿ ಬನ್ನಂಜೆಯವರು ನೆನಪಿಸಿಕೊಂಡಿದ್ದಾರೆ].\nಹಿಂದೆ ಯಜ್ಞ ಮಾಡುವಾಗ ಶಮಿ ಮತ್ತು ಅರಣಿ(ಅರಳಿ) ಸಮಿತೆಯನ್ನು ಮಥನ ಮಾಡಿ ಅದರಿಂದ ಅಗ್ನಿ ಕಿಡಿ\nತರಿಸಿ, ಅಗ್ನಿ ಸೃಷ್ಟಿ ಮಾಡುತ್ತಿದ್ದರು. ಯಜ್ಞದಲ್ಲಿ ಅರಳಿಯ ಸಮಿತೆಯನ್ನು ಮುಖ್ಯವಾಗಿ ಉಪಯೋಗಿಸುತ್ತಾರೆ.\nಅಶ್ವತ್ಥಮರದ ಸಮಿತೆಯನ್ನು ಕಾಷ್ಟವಾಗಿ ಯಜ್ಞದಲ್ಲಿ ಉಪಯೋಗಿಸಿದರೆ, ಅಲ್ಲಿ ಉರಿಯುವ ಬೆಂಕಿಯ\nಜ್ವಾಲೆಯಲ್ಲಿ ಒಂದು ವಿಶಿಷ್ಟ ಶಕ್ತಿ ಹೊರ ಹೊಮ್ಮುತ್ತದೆ. ಹೇಗೆ ಸೂರ್ಯನ ಕಿರಣದಲ್ಲಿ ಏಳು ಬಣ್ಣವಿದೆಯೋ ಹಾಗೇ\nಅಗ್ನಿಯಲ್ಲಿ ಏಳು ಬಣ್ಣವಿದೆ. ಮುಂಡಕ ಉಪನಿಷತ್ತಿನಲ್ಲಿ ಅಗ್ನಿಯ ಜ್ವಾಲೆಯಿಂದ ಹೊಮ್ಮುವ ಏಳು ಬಣ್ಣವನ್ನು ಕಾಳಿ,\nಕರಾಳಿ, ಮನೋಜವಾಚ, ಸುಲೋಹಿತಾಯಾಚ, ಸುಧೂಮ್ರವರ್ಣಾ, ಸ್ಫುಲಿಂಗಿನೀ, ವಿಶ್ವರುಚಿ ಎಂದು\nಕರೆದಿದ್ದಾರೆ. ಅಗ್ನಿಯ ಈ ಏಳು ಬಣ್ಣವನ್ನು ಸೂರ್ಯ ಕಿರಣದ ಏಳು ಬಣ್ಣದೊಂದಿಗೆ ಸಂಕ್ರಾಂತಗೊಳಿಸಿ\nವಾತಾವರಣದಲ್ಲಿ ಅದರ ಪ್ರಭಾವ ತರುವುದೇ ಯಜ್ಞ. ಈ ಕ್ರಿಯೆಗೆ ಅಶ್ವತ್ಸಸಮಿತೆ ಒಂದು ಪ್ರಮುಖ ಸಾಧನ.\n\nಇಂದು ಹಲವರು ಅಶ್ವತ್ಥಮರದಲ್ಲಿ ದೇವತಾ ಸನ್ನಿಧಾನವಿದೆ. ಎಂದು ಅದಕ್ಕೆ ಪ್ರದಕ್ಷಿಣೆ ಬರುತ್ತಾರೆ.\nಮಕ್ಕಳಾಗದಿದ್ದಾಗ ಜ್ಯೋತಿಷಿಗಳು ಅಶ್ವತ್ಥ ಪ್ರದಕ್ಷಿಣೆ ಬರುವಂತೆ ಹೇಳುತ್ತಾರೆ. ಇದು ಏಕೆ ಎನ್ನುವ ಕಲ್ಪನೆ ಇಲ್ಲದ\nಜನ ಇದೆಲ್ಲವೂ ಮೂಢನಂಬಿಕೆ ಎಂದು ಮಾತನಾಡಿಕೊಳ್ಳುತ್ತಾರೆ. ಜಗತ್ತಿನಲ್ಲಿರುವ ಎಲ್ಲಾ ಮರಗಳಿಗಿಂತ ಹೆಚ್ಚು\n\nಆಮ್ಲಜನಕ ಕೊಡುವ ವೃಕ್ಷ ಅಶ್ವತ್ಥ. ಇಂತಹ ಶುದ್ಧ ವಾಯುವಿನ ಉಸಿರಾಟದಿಂದ ಗರ್ಭದೋಷ ಸರಿಹೋಗುವ\nಸಾಧ್ಯತೆ ಇದೆ ಎಂದು ಇಂದು ವಿಜ್ಞಾನ ಕೂಡಾ ಒಪ್ಪಿಕೊಂಡಿದೆ. ಹಿಂದಿನ ಕಾಲದಲ್ಲಿ ಖುಷಿಗಳು ಅಶ್ವತ್ಥ ಮರದ\nಬುಡದಲ್ಲಿ ಕುಳಿತು ವೇದಾಧ್ಯಾಯನ ಮಾಡುತ್ತಿದ್ದರು. ಹೀಗೆ ಅಶ್ವತ್ಥ ಮರದಲ್ಲಿ ಭಗವಂತನ ವಿಶೇಷ ವಿಭೂತಿ ಆ\nಮರಕ್ಕೆ ಇಂತಹ ಅನೇಕ ವಿಶೇಷ ಶಕ್ತಿಯನ್ನು ಕೊಟ್ಟಿದೆ.\n\nಇಲ್ಲಿ ಬಂದಿರುವ ಭಗವಂತನ ನಾಮ “ಅಶ್ವತ್ಥಃ”. ವೇದವನ್ನು ಉಪದೇಶ ಮಾಡಿದ ಭಗವಂತನ ವಿಶೇಷ\nಅವತಾರ ಅಶ್ವರೂಪ ಹಯಗ್ರೀವ. ಅಶ್ವದ ಹಾಗೆ ಇದ್ದು ವೇದೋಪದೇಶ ಮಾಡಿದ ಭಗವಂತನನ್ನು 'ಅಶ್ವತ್ಥಃ'\nಎಂದು ಕರೆಯುತ್ತಾರೆ.\n\nಮುಂದುವರಿದು ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ದೇವರ್ಷೀಣಾಂ ಚ ನಾರದಃ” ಎಂದು. ನಾರದ ಗಂಧರ್ವರಲ್ಲಿ ಒಬ್ಬ. ಆದರೆ\nಭಗವಂತನ ವಿಶೇಷ ಸನ್ನಿಧಾನದಿಂದ ಆತ ತುಂಬಾ ಎತ್ತರಕ್ಕೇರಿ ದೇವರ್ಷಿಯಾದ. ನಾರದ ಭಗವಂತನನ್ನು\nಪಡೆದದ್ದು ಮಹಾ ಸಾಧನೆಯಿಂದ. ಹಿಂದಿನ ಬ್ರಹ್ಮಕಲ್ಪದಲ್ಲಿ ನಾರದ ಒಂದು ಬಡ ಕುಟುಂಬದಲ್ಲಿ ಹುಟ್ಟಿದ್ದ. ಆತನ\nತಾಯಿ ಖುಷಿ-ಮುನಿಗಳ ಆಶ್ರಮದಲ್ಲಿ ಕೆಲಸ ಮಾಡಿಕೊಂಡು ಬದುಕುತಿದ್ದಳು. ಪುಟ್ಟ ಮಗುವಾಗಿದ್ದ ಈತ\nಖುಷಿಗಳ ಅಧ್ಯಾತ್ಮ ಸಂಭಾಷಣೆಯನ್ನು ಕೇಳುತ್ತಾ ಬೆಳೆದ. ಈತ ಐದು ವರ್ಷದವನಿದ್ದಾಗ ಆತನ ತಾಯಿ ಹಾವು\nಕಚ್ಚಿ ಸಾಯುತ್ತಾಳೆ. ತಿಳಿದವರು ಹೇಳುವಂತೆ- “ನಮಗೆ ದೇವರೇ “ನಾಥ' ಎಂದು ಗೊತ್ತು ಮಾಡಿಸಲು\nಭಗವಂತ ನಮ್ಮನ್ನು ಮೊದಲು 'ಅನಾಥ' ಮಾಡುತ್ತಾನೆ”. ಹಾಗೆ ಅನಾಥನಾದ ಈತ ತನ್ನ ಐದನೇ\nವರ್ಷದಿಂದಲೇ, ಖುಷಿಗಳಿಂದ ತಿಳಿದ ಜ್ಞಾನದಿಂದ ಸಾಧನೆ ಆರಂಭಿಸುತ್ತಾನೆ. ಆದರೆ ಆತನಿಗೆ ಆ ಜನ್ಮದಲ್ಲಿ\nಭಗವಂತನ ದರ್ಶನವಾಗುವುದಿಲ್ಲ. ಆದರೆ ಆತ ಭಗವಂತನ ವಾಣಿಯನ್ನು 'ಕೇಳಿದ'. “ಈ ಜನ್ಮದಲ್ಲಿ ನನ್ನನ್ನು\nಕಾಣುವ ಪ್ರಯತ್ನ ಮಾಡಬೇಡ. ನೀನು ಮುಂದಿನ ಕಲ್ಪದಲ್ಲಿ ಸದಾ ನನ್ನನ್ನು ಕಾಣುವೆ” ಎಂದು. ನಂತರ ಈತ ಈ\nಬ್ರಹ್ಮಕಲ್ಪದಲ್ಲಿ ನಾರದನಾಗಿ ಹುಟ್ಟಿ ಭಗವಂತನ ಮಹಾ ಅನುಗ್ರಹಕ್ಕೆ ಪಾತ್ರನಾದ.\n\nನಾರದರು. ನಮ್ಮ ಅಂತಃಪ್ರಜ್ಞೆಯ ಅಭಿಮಾನಿ ದೇವತೆ. ಹಿಂದಿನ ಕಾಲದ ಕಥೆಗಳಲ್ಲಿ ಕಾಣುವಂತೆ\nಯಾವುದಾದರು ಒಳ್ಳೆಯ ಕೆಲಸವಾಗಬೇಕಾದರೆ ಅಲ್ಲಿ ನಾರದರು ಬಂದು ಹೇಳಿ ಹೋಗುತ್ತಿದ್ದರು. ಉದಾಹರಣೆಗೆ\nವಾಲ್ಮೀಕಿಗೆ ರಾಮಾಯಣ ಬರೆಯುವಂತೆ ಹೇಳಿ ಹೋದವರು ನಾರದರು. ಇಲ್ಲಿ ನಮಗೆ ಒಂದು ಪ್ರಶ್ನೆ ಬರುತ್ತದೆ.\nಈಗ ಏಕೆ ನಾರದರು ಬರುವುದಿಲ್ಲ, ಏಕೆ ನಮಗೆ ಮಾರ್ಗದರ್ಶನ ಸಿಗುವುದಿಲ್ಲ ಎಂದು. ನಾರದರನ್ನು ನಾವು\nಕರೆದರೆ ಖಂಡಿತ ಇವತ್ತಿಗೂ ಬರುತ್ತಾರೆ! “ನಾರದ' ಅಂದರೆ ನಮ್ಮ ಅಂತರಂಗದ ಧ್ವನಿ(inner voice).\nನಾವು ನಮ್ಮ ಆತ್ಮದ ಕರೆಗೆ ಕಿವಿ ಕೊಟ್ಟರೆ ಅಲ್ಲಿ ನಾರದರು ಮಾತನಾಡುತ್ತಾರೆ. ನಾವು ನಮ್ಮ ಒಳಗಿನ\nಸಂದೇಶವನ್ನು ಆಲಿಸಲು ಅಭ್ಯಾಸ ಮಾಡಿದರೆ ಆಗ ನಮ್ಮ ಅಜ್ಞಾಚಕ್ರ ತೆರೆದುಕೊಳ್ಳುತ್ತದೆ. ಇದರಿಂದ 'ಈ ರೀತಿ\nಮಾಡು' ಎನ್ನುವ ಸಂದೇಶ(divine message) ಬರುತ್ತದೆ. ಇದೇ ಅಶರೀರವಾಣಿ ಅಥವಾ ಅಂತಃರ್ವಾಣಿ. ಇದೇ\nನಾರದ. ಪ್ರತ್ಯಕ್ಷ ಕಾಣಲಾಗದಿದ್ದರೂ ಕೂಡಾ ಅವರನ್ನು ಕೇಳಬಹುದು. ನಾರದರಿಗೆ ಈ ಎಲ್ಲಾ ವಿಶಿಷ್ಟ ಶಕ್ತಿ\nಭಗವಂತನ ವಿಶೇಷ ಸನ್ನಿಧಾನದಿಂದ ಬಂತು.\n\nಇಲ್ಲಿ ಬಂದಿರುವ ಭಗವಂತನ ವಿಭೂತಿನಾಮ “ನಾರದಃ. ನರರ ಅಜ್ಞಾನವನ್ನು ಕಳೆದು(ನಾರ-ಧ್ಯತಿ), ಅವರು\nಬಯಸಿದ್ದನ್ನು ಧಾರೆ ಎರೆಯುವ(ನಾರ-ದದಾತಿ) ಭಗವಂತ ನಾರದಃ.\n\nನಾರದರ ನಂತರ ಗಂಧರ್ವರಲ್ಲಿ ತನ್ನ ವಿಶೇಷ ವಿಭೂತಿಯನ್ನು ಕೃಷ್ಣ ವಿವರಿಸುತ್ತಾನೆ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ\n“ಗಂಧರ್ವರಲ್ಲಿ ಚಿತ್ರರಥ ನಾನು” ಎಂದು. ದೇವಲೋಕದ ಪರಿಚಾರಿಕೆ ಮಾಡುವ ಉಪದೇವತಾ ಗಣ\nಗಂಧರ್ವರು. ಇವರು ಅವಾಂತರ ದೇವತೆಗಳು. ಈ ಗಣದ ರಾಜ ಚಿತ್ರರಥ. “ರಾಜಾ ಪ್ರತ್ಯಕ್ಷ ದೇವತಾ'\nಎನ್ನುವಂತೆ ಭಗವಂತ ಚಿತ್ರರಥನಲ್ಲಿ ವಿಶೇಷ ವಿಭೂತಿಯಾಗಿ ಸನ್ನಿಹಿತನಾಗಿದ್ದಾನೆ. ಇಲ್ಲಿ ಬಂದಿರುವ\nಭಗವಂತನ ವಿಭೂತಿನಾಮ 'ಚಿತ್ರರಥಃ'. ವಿಚಿತ್ರವಾದ ರಥ ಉಳ್ಳ ಭಗವಂತ ಚಿತ್ರರಥಃ. ಭಗವಂತನ ವಾಹನ-\nಗರುಡ. ಇದು ಇತರ ಎಲ್ಲಾ ವಾಹನಗಳಿಗಿಂತ ವಿಶಿಷ್ಟ. ಇಂತಹ ರಥದಲ್ಲಿ ಸಂಚರಿಸುವ ಭಗವಂತ ಚಿತ್ರರಥಃ.\nಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ಸಿದ್ಧಾನಾಂ ಕಪಿಲೋ ಮುನಿಃ” ಎಂದು. ಇತಿಹಾಸದಲ್ಲಿ ಇಬ್ಬರು ಕಪಿಲಮುನಿಗಳು ಬರುತ್ತಾರೆ.\nಇವರಿಬ್ಬರೂ ಸಾಂಖ್ಯವನ್ನು ಹೇಳಿದವರು. ಆದರೆ ಒಬ್ಬ ಭಗವಂತನನ್ನು ನಂಬದವ. ಆದ್ದರಿಂದ ಇಲ್ಲಿ ಬಂದಿರುವ\nಕಪಿಲಮುನಿ-ಕಪಿಲ ವಾಸುದೇವ. ಸಾಂಖ್ಯವನ್ನು ಮೂಲತಃ ಜಗತ್ತಿಗೆ ಕೊಟ್ಟ ಸಾಕ್ಷಾತ್‌ ಭಗವಂತನ ಅವತಾರ.\nಸ್ವಾಯಂಭುವ ಮನುವಿನ ಮಗಳು ದೇವಭೂತಿ ಹಾಗೂ ಕರ್ಧಮ ಪ್ರಜಾಪತಿಯ ದಾಂಪತ್ಯ ಫಲದಲ್ಲಿ\nಮೂಡಿಬಂದ ಭಗವಂತನ ಅವತಾರ. ವೇದವ್ಯಾಸರು ಕೂಡಾ ಕಪಿಲ ಹೇಳಿರುವುದನ್ನೇ ನಮ್ಮ ಮುಂದೆ ಪ್ರಸ್ತುತಿ\nಮಾಡಿರುವುದು. ಹೊಸತನ್ನು ಜಗತ್ತಿಗೆ ಕೊಟ್ಟ ಭಗವಂತನ ಅವತಾರ “ಕಪಿಲಾವತಾರ'.\n\nಇಲ್ಲಿ ಬಂದಿರುವ ಭಗವಂತನ ವಿಭೂತಿನಾಮ “ಕಪಿಲಃ'. ಕ-ಪಿ-ಲ; ಇಡೀ ಜಗತ್ತನ್ನು ಪಾಲಿಸುವಪಿ), ಮತ್ತು\nಲಯಗೊಳಿಸುವ(ಲ), ಆನಂದಮೂರ್ತಿ(ಕ) ಭಗವಂತ ಕಪಿಲ. ಸದಾ ಆನಂದವನ್ನು ಪಾನಮಾಡುವ,\nಅದ್ಭುತವಾದ ಸಾಂಖ್ಯದ ಮೂಲಕ ವಿಶ್ವದ ರಹಸ್ಯವನ್ನು ತೆರೆದಿಟ್ಟ ಭಗವಂತ “ಕಪಿಲಃ'.\n\nಋಷಿ, ಬ್ರಹ್ಮರ್ಷಿ, ದೇವರ್ಷಿ, ಮಹರ್ಷಿಗಳು ಹೀಗೆ ಬ್ರಹ್ಮ ತೇಜಸ್ಸು ಮತ್ತು ಅವರು ಮಾಡುವ ವೇದಾಧ್ಯಾಯನ,\nತಪಸ್ಸು, ಯಜ್ಞ-ಎಲ್ಲದರ ಬಗ್ಗೆ ಹೇಳಿದ ಕೃಷ್ಣ, ಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ಕ್ಷಾತ್ರತೇಜಸ್ಸಿನ ಬಗ್ಗೆ ಹೇಳುತ್ತಾನೆ.",
  "10.27": "ಉಚ್ಚೆಃಶ್ರವಸಮ್‌ ಅಶ್ವಾನಾಮ್‌ ವಿದ್ಧಿ ಮಾಮ್‌ ಅಮೃತ ಉದ್ಭವಮ್‌ ।\n\nಐರಾವತಮ್‌ ಗಜೇಂದ್ರಾಹಾಮ್‌ ನರಾಣಾಮ್‌ ಚ ನರಾಧಿಪಮ್‌-ಕುದುರೆಗಳಲ್ಲಿ ಕಡಲಲ್ಲಿ ಮೂಡಿಬಂದ\nಉಚ್ಚೆಃಶ್ರವಸ್ಸನ್ನು, ಹಿರಿಯಾನೆಗಳಲ್ಲಿ ಐರಾವತವನ್ನು, ಮನುಜರಲ್ಲಿ ಒಡೆಯನಾದ ಅರಸನನ್ನು[ಉನ್ನತಕೀರ್ತಿ\nಪಡೆದು \"ಉಚ್ಚೆಃಶ್ರವಸ್‌' ಎನ್ನಿಸಿ ಉಚ್ಚೆಃಶ್ರವದಲ್ಲಿರುವವನು, ಐರಾ-ಲಕ್ಷ್ಮಿಗೆ, ಅವನರಕ್ಷಕನಾಗಿ 'ಐರಾವತ'\nಎನ್ನಿಸಿ ಐರಾವತದಲ್ಲಿರುವವನು, ನರರಿಗೆಲ್ಲಾ ಒಡೆಯನಾದ್ದರಿಂದ “ನರಾಧಿಪ' ಎನ್ನಿಸಿ ಅರಸನಲ್ಲಿರುವವನು]\nನಾನೆಂದು ತಿಳಿ,\n\nಹಿಂದೆ ಸೇನೆಯಲ್ಲಿ ಮುಖ್ಯವಾದ ಅಂಗಗಳಾಗಿ ಕುದುರೆ ಮತ್ತು ಆನೆಗಳನ್ನು ರಾಜರು ಬಳಸುತ್ತಿದ್ದರು. ಕೃಷ್ಣ ಈ\nಶ್ಲೋಕದಲ್ಲಿ ಕುದುರೆ, ಆನೆ ಮತ್ತು ರಾಜರಲ್ಲಿ ತನ್ನ ವಿಶೇಷ ವಿಭೂತಿಯನ್ನು ಹೇಳಿದ್ದಾನೆ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ\n“ಸಮುದ್ರ ಮಥನದಲ್ಲಿ ಅಮೃತದ ಜೊತೆಗೆ ಹುಟ್ಟಿದ ಅಶ್ವ “ಉಚ್ಚೆಃಶ್ರವಸ್ಸು' ಮತ್ತು ಹಿರಿಯಾನೆ “ಐರಾವತ'\n\nನಾನೆಂದು ತಿಳಿ” ಎಂದು. ಈ ಎರಡೂ ಪ್ರಾಣಿಗಳು ಬಹಳ ವಿಶೇಷ ಪ್ರಾಣಿಗಳು. ಕುದುರೆ ಮತ್ತು ಆನೆ\nಸ್ವಾಮಿನಿಷ್ಠೆಗೆ ಹೆಸರಾದ ಪ್ರಾಣಿಗಳು. ಇವು ತನ್ನನ್ನು ಪ್ರೀತಿಯಿಂದ ಸಾಕುವ ಧನಿಗೆ ಎಂದೂ ಮೋಸ\nಮಾಡುವುದಿಲ್ಲ. ಇನ್ನು ನರರಲ್ಲಿ ಶ್ರೇಷ್ಠ “ನರಾಧಿಪ'. ಮನುಕುಲಕ್ಕೆ ನಾಯಕರಾಗಿ ನಿಂತು ಧರ್ಮನಿಷ್ಠರಾಗಿ\nಜನಪಾಲನೆ ಮಾಡುವ ಮುಖಂಡರಲ್ಲಿ ಭಗವಂತನ ವಿಶೇಷ ಸನ್ನಿಧಾನವಿರುತ್ತದೆ. ಹಿಂದೆ ರಾಜ್ಯಭಾರ ಮಾಡಿದ\nಧರ್ಮರಾಜ, ಪರೀಕ್ಷಿತ ಇತ್ಯಾದಿ ರಾಜರನ್ನು ಇಲ್ಲಿ ನಾವು ನೆನಪಿಸಿಕೊಳ್ಳಬಹುದು.\n\nಇಲ್ಲಿ ಬಂದಿರುವ ಭಗವಂತನ ವಿಭೂತಿನಾಮ ಉಚ್ಚೆಶ್ರವಸ್ಸು, ಐರಾವತಃ ಮತ್ತು ನರಾಧಿಪಃ. “ಶ್ರವಸ್ಸು' ಎಂದರೆ\nಕೀರ್ತಿ, ಜ್ಞಾನ, ಕರ್ಮ. ಹಬ್ಬಿರುವ ಕೀರ್ತಿ ಹೊಂದಿರುವ, ಮಹಾಜ್ಞಾನಿಯಾದ ಭಗವಂತ ಈ ಸೃಷ್ಟಿ-ಸ್ಥಿತಿ-\nಸಂಹಾರವೆಂಬ ಮಹಾಕರ್ಮವನ್ನು ಸದಾ ಮಾಡುತ್ತಿರುವ “ಉಚ್ಚೆಃಶ್ರವಸ್ಸು'. ಐರಾ ಎಂದರೆ ಭೂದೇವಿಯಲ್ಲಿ\nಸನ್ನಿಹಿತಳಾಗಿರುವ ಲಕ್ಷ್ಮಿ. ಇಂತಹ ಲಕ್ಷ್ಮಿಗೆ ಪತಿಯಾಗಿರುವ ಭಗವಂತ “ಐರಾವತಃ'. ನರರಿಗೆ, ಸರ್ವ\nಜೀವಜಾತಕ್ಕೆ ಅಧಿಪತಿಯಾಗಿ, ಅರಸರಲ್ಲಿ ಸನ್ನಿಹಿತನಾಗಿರುವ ಭಗವಂತ “ನರಾಧಿಪಃ.\n",
  "10.28": "ಆಯುಧಾನಾಮ್‌ ಅಹಮ್‌ ವಜ್ರಮ್‌ ಧೇನೂನಾಮ್‌ ಅಸ್ಮಿ ಕಾಮಧುಕ್‌ |\n\nಪ್ರಜನಃ ಚ ಅಸ್ಮಿ ಕಂದರ್ಪಃ ಸರ್ಪಾಣಾಮ್‌ ಅಸ್ಮಿ ವಾಸುಕಿಃ -ಆಯುಧಗಳಲ್ಲಿ ವಜ್ರಾಯುಧ ನಾನು.\n[ಅರಿವರ್ಜಿತನಾದ್ದರಿಂದ “ವಜ್ರ' ಎನ್ನಿಸಿ ವಜ್ರಾಯುಧದಲ್ಲಿದ್ದೇನೆ.] ಹಸುಗಳಲ್ಲಿ ಕಾಮಧೇನು ನಾನು.\n[ಕಾಮ-ಬಯಸಿದ್ದನ್ನು, ಧುಕ್‌-ಕರೆಯುವುದರಿಂದ “ಕಾಮಧುಕ್” ಎನ್ನಿಸಿ. ಕಾಮಧೇನುವಿನಲ್ಲಿದ್ದೇನೆ.]\nಸಂತಾನವನ್ನೀಯುವ ಕಾಮದೇವ [ಕಂ-ಸುಖದ, ದರ-ಹಲವು ಬಗೆಗಳನ್ನು, ಪ-ಉಣ್ಣಿಸುವುದರಿಂದ “ಕಂದರ್ಪ'\nಎನ್ನಿಸಿ ಕಾಮದೇವನಲ್ಲಿದ್ದು ಅವನಿಗೆ ಹುಟ್ಟಿನ ಸೆಳೆತದ ಶಕ್ತಿಯನ್ನಿತ್ತವನು] ನಾನು. ಹಾವುಗಳಲ್ಲಿ ವಾಸುಕಿ ನಾನು.\n[ವಾಸು-ಎಲ್ಲೆಡೆ ವಾಸಮಾಡಿ, ಕಿ-ಸುಖವನ್ನೀಯುವುದರಿಂದ 'ವಾಸುಕಿ' ಎನ್ನಿಸಿ ವಾಸುಕಿಯಲ್ಲಿದ್ದೇನೆ.]\n\nಆಯುಧಗಳಲ್ಲಿ ಸರ್ವಶ್ರೇಷ್ಠ ಆಯುಧ ಭಗವಂತ ಧರಿಸುವ ಸುದರ್ಶನ. ಭಗವಂತನ ಆಯುಧವನ್ನು ಬಿಟ್ಟರೆ\nಶ್ರೇಷ್ಠ ಆಯುಧ ವಜ್ರಾಯುಧ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ಆಯುಧಗಳಲ್ಲಿ ವಜ್ರಾಯುಧ ನಾನು” ಎಂದು. ಈ\nವಜ್ರಾಯುಧ ಇಂದ್ರನ ಆಯುಧ. ಇದಕ್ಕೆ ಮೂರು ಲೋಕವನ್ನು ನಿಯಂತ್ರಿಸುವ ಶಕ್ತಿಯನ್ನು ಭಗವಂತ ಕೊಟ್ಟ.\nವ್ರತ್ರನನ್ನು ಸಂಹಾರ ಮಾಡಲು ಭಗವಂತನ ಆದೇಶದಂತೆ ದಧೀಚಿ ಎನ್ನುವ ಮುನಿಯ ಪೂರ್ಣ ತಪಸ್ಸಿನ\nಫಲವನ್ನು ಆವಾಹನೆ ಮಾಡಿ ನಿರ್ಮಾಣಗೊಂಡ ಆಯುಧ ವಜ್ರಾಯುಧ. ಮಳೆ ಬಂದಾಗ ಕಾಣುವ ಸಿಡಿಲು-\nಮಿಂಚನ್ನು ವಜ್ರಾಯುಧದ ಪ್ರತೀಕವೆನ್ನುತ್ತಾರೆ. ಈ ಆಯುಧದಲ್ಲಿ ಭಗವಂತ \"ವಜ್ರ ನಾಮಕನಾಗಿ\nಸನ್ನಿಹಿತನಾಗಿದ್ದಾನೆ. “ವರ್ಜನಾತ್‌ ಇತಿ ವಜ್ರಃ'. ಶತ್ರುಗಳನ್ನು, ಸಮಸ್ತ ದೋಷವನ್ನು, ವರ್ಜನೆ ಮಾಡುವ\nಭಗವಂತ ವಜ್ರಃ.\n\nಅಸ್ತ್ರದ ಬಗ್ಗೆ ಹೇಳಿದ ಕೃಷ್ಣ ಮುಂದೆ ವಿಶ್ವಾಮಿತ್ರನ ಸಮಸ್ತ ಅಸ್ತ್ರವನ್ನು ನಾಶಮಾಡಿದ ವಸಿಷ್ಠಮುನಿಯ\nಕಾಮಧೇನುವಿನ ಬಗ್ಗೆ ಹೇಳುತ್ತಾನೆ. ಪ್ರಾಣಿಗಳಲ್ಲೇ ಶ್ರೇಷ್ಠ ಪ್ರಾಣಿ-ಧೇನು(ಹಸು). ನಮ್ಮ ಜೀವಮಾನವಿಡೀ\nನಮಗೆ ಹಾಲುಣಿಸಿ ಪೋಷಿಸುವ ಭಗವಂತನ ವಿಶಿಷ್ಟ ವಿಭೂತಿ ಹಸು. ಈ ಕಾರಣಕ್ಕಾಗಿ ಕೃಷ್ಣ ಬಾಲಕನಿದ್ದಾಗ\nಗೋಪೂಜೆಯನ್ನು ಚಾಲ್ತಿಗೆ ತಂದ. ಹಸುವಿನ ಮಲ-ಮೂತ್ರ ಕೂಡಾ ತ್ಯಾಜ್ಯವಲ್ಲ. ಯಾವುದರಿಂದಲೂ\nಗುಣವಾಗದ ಚರ್ಮರೋಗ ಗೋಮಯ ಮತ್ತು ಮೃತ್ರ್ತಿಕೆ(ಕೆಂಪು ಮಣ್ಣು)ಯಿಂದ ಸ್ನಾನ ಮಾಡಿದರೆ ಆ ರೋಗ\nಗುಣವಾಗುತ್ತದೆ. ಮನೆ ಮುಂದೆ ಸಗಣಿ ಸಾರಿಸುವುದರಿಂದ ಅಲ್ಲಿ ಕ್ರಿಮಿ ಕೀಟ ಇಲ್ಲವಾಗುತ್ತದೆ. ಗೋಮಯದಲ್ಲಿ\nಲಕ್ಷ್ಮಿಯ ಸನ್ನಿಧಾನವಿದೆ. ಎಂದು ಮಹಾಭಾರತದಲ್ಲಿ ಬರುವ ಒಂದು ಕಥೆಯಲ್ಲಿ ಹೇಳಲಾಗಿದೆ. ಹೀಗೆ\nಅನೇಕಾನೇಕ ಉಪಯೋಗ ಹಸುವಿನಿಂದ. ಭಗವಂತ ಬಯಸಿದ್ದನ್ನು ಕೊಡುವ “ಕಾಮಧುಕ್‌' ನಾಮಕನಾಗಿ\nಕಾಮಧೇನುವಿನಲ್ಲಿ ವಿಭೂತಿಯಾಗಿ ನಿಂತ.\n\nಈ ಪ್ರಪಂಚದಲ್ಲಿರುವ ಜೀವಿಗಳಲ್ಲಿ ಗಂಡು-ಹೆಣ್ಣಿನ ನಡುವೆ ಹುಟ್ಟಿನ ಸೆಳೆತ(Sexual desire)ವಾಗಿ ನಿಂತಿರುವವ-\nಸಂತಾನವನ್ನೀಯುವ ಕಾಮದೇವ. ಈ ಕಾಮದೇವ(ಕಂದರ್ಪ)ನಲ್ಲಿ ಭಗವಂತನ ವಿಶಿಷ್ಟ ಶಕ್ತಿ ಅಡಗಿದೆ.\nಸೃಷ್ಟಿಯಲ್ಲಿ ಸಂತಾನ ಕ್ರಿಯೆ ನಡೆಯುವುದಕ್ಕೋಸ್ಕರ ಅಧಮ್ಯ ಬಯಕೆಯನ್ನು ಎಲ್ಲರೊಳಗೆ ತುಂಬಿ, ಅಲ್ಲಿ\nಭಗವಂತ ಕೂತ. ಈ ಕಾರಣದಿಂದ ಭಗವಂತನ ಅನುಗ್ರಹವಿಲ್ಲದೆ ಲೀಲಾಜಾಲವಾಗಿ ಯಾರೂ ಕೂಡಾ ಈ\nಶಕ್ತಿಯಿಂದೀಚೆಗೆ ಬರಲಾರರು. ಬಲವಂತವಾಗಿ ಅದನ್ನು ಬಿಡಲಾಗದು. ಭಗವಂತ ಕಂದರ್ಪಃ ನಾಮಕನಾಗಿ\nಕಾಮದೇವನಲ್ಲಿ ತುಂಬಿದ್ದಾನೆ. ಮನುಷ್ಯನಿಗೆ ಅನೇಕ ರೀತಿಯ ಬಯಕೆಗಳನ್ನು ಕೊಟ್ಟು, ಆ ಬಯಕೆಯಿಂದ\nಅವರನ್ನು ಸಂತೃಪ್ಪಿಗೊಳಿಸಿ, ವಿಚಿತ್ರ ಸುಖದ ಸುಪ್ಪತ್ತಿಗೆಯಲ್ಲಿ ಓಲಾಡಿಸುವ ಭಗವಂತ 'ಕಂದರ್ಪಃ'.\nಕಾಮದೇವ-ಮನ್ಮಥನ ನಂತರ ಕಾಮದ ಸಂಕೇತವಾದ ಸರ್ಪದ ಬಗ್ಗೆ ಕೃಷ್ಣ ವಿವರಿಸುತ್ತಾನೆ. ಹೊಟ್ಟೆಯನ್ನು\nಹೊಸೆದುಕೊಂಡು ಹೋಗುವ ಸರೀಸೃಪವನ್ನು ಸರ್ಪ ಎನ್ನುತ್ತಾರೆ. ಸರೀಸೃಪಗಳಿಗೆಲ್ಲಾ ರಾಜ ವಾಸುಕಿ.\nಭಗವಂತ 'ವಾಸುಕಿಃ' ನಾಮಕನಾಗಿ ನಿಂತು, ವಾಸುಕಿಗೆ ಈ ಸ್ಥಾನವನ್ನು ಕೊಟ್ಟ. ಭಗವಂತ ಇಲ್ಲದ ಸ್ಥಳವಿಲ್ಲ.\nಎಲ್ಲೆಡೆ ವಾಸಮಾಡುವ ಭಗವಂತ 'ವಾಸುಕಿಃ'\n",
  "10.29": "ಅನಂತಃ ಚ ಅಸ್ಮಿ ನಾಗಾನಾಮ್‌ ವರುಣಃ ಯಾದಸಾಮ್‌ ಅಹಮ್‌ |\n\nಪಿತ್ಯಣಾಮ್‌ ಅರ್ಯಮಾ ಚ ಅಸ್ಮಿ ಯಮಃ ಸಂಯಮತಾಮ್‌ ಅಹಮ್‌ -ನಾಗರಹಾವುಗಳಲ್ಲಿ ಶೇಷ ನಾನು.\n[ಅಳಿವಿರದ್ದರಿಂದ \"ಅನಂತ' ಎನ್ನಿ ಸಿ ಶೇಷನಲ್ಲಿದ್ದೇನೆ.] ಜಲಚರಗಳ ಒಡೆಯ ವರುಣ ([ವರ್‌ಹಿರಿದಾದ,\nಣ-ಆನಂದಸ್ವರೂಪನಾದ್ದರಿಂದ “ವರುಣ' ಎನ್ನಿಸಿ ವರುಣನಲ್ಲಿದ್ದು ಅವನಿಗೆ ಜಲಚರಗಳ ಒಡೆತನವನ್ನಿತ್ತವನು]\nನಾನು. ಪಿತೃದೇವತೆಗಳಲ್ಲಿ ಅರ್ಯಮ ನಾನು. [ಅರ್ಯ-ಅರಿಯಬೇಕಾದವನು ಮತ್ತು ಮಾ:ಅರಿತವನು\nಆದ್ದರಿಂದ \"ಅರ್ಯಮನ್‌' ಎನ್ನಿಸಿ, ಪಿತೃಪತಿಯಾದ ಅರ್ಯಮನೆಂಬ ಆದಿತ್ಯನಲ್ಲಿದ್ದೇನೆ.] ದಂಡಿಸುವವರಲ್ಲಿ\n\nಯಮ[ನಿಯಮಿಸುವುದರಿಂದ “ಯಮ' ಎನ್ನಿಸಿ, ಯಮನಲ್ಲಿದ್ದು ಅವನಿಗೆ ಪಾಪಿಗಳನ್ನು ದಂಡಿಸುವ\nಹೊಣೆಯಿತ್ತವನು]ನಾನು.\n\nಸರ್ಪಗಳ ಜಾತಿಯಲ್ಲಿ ಹೆಡೆ ಉಳ್ಳದ್ದು 'ನಾಗರ'. ನಾಗರದಲ್ಲಿ ಅತ್ಯಂತ ಶ್ರೇಷ್ಠ “ಶೇಷ'. ಬಲರಾಮನಾಗಿ,\nಲಕ್ಷ್ಮಣನಾಗಿ, ಸದಾ ಭಗವಂತನ ಹಾಸಿಗೆಯಾಗಿ ಇರುವ ಬಹಳ ದೊಡ್ಡ ದೇವತಾಶಕ್ತಿ ಶೇಷ. ಶೇಷ ಭೂಮಿಯ\nಆಕರ್ಷಣ ಶಕ್ತಿಯಾದ (Gravity) ಸಂಕರ್ಷಣ. ಹೀಗಾಗಿ ಭೂಮಿಯನ್ನು ಶೇಷ ಹೊತ್ತಿದ್ದಾನೆ ಎನ್ನುತ್ತಾರೆ. ಇಂತಹ\nಶೇಷನಲ್ಲಿ ಭಗವಂತ ವಿಶೇಷವಾಗಿ ಸನ್ನಿಹಿತನಾಗಿದ್ದಾನೆ. ಹೆಡೆಯಿರುವ ಹಾವುಗಳಿಗೆಲ್ಲಾ ಮೂಲಶಕ್ತಿಯಾಗಿ\nಶೇಷನಲ್ಲಿ ತುಂಬಿದ, ಎಂದೂ ಅಳಿವಿರದ ಶೇಷಶಯನ ಭಗವಂತ \"ಅನಂತಃ.\n\n“ಜಲಚರ ಪ್ರಾಣಿಗಳಲ್ಲಿ ಅವುಗಳ ಒಡೆಯ “ವರುಣ' ನಾನು” ಎನ್ನು ತ್ತಾನೆ ಕೃಷ್ಣ. ನೀರಿನ ಆವರಣದಲ್ಲಿ ಅನೇಕ\nಜಲಚರ ಪ್ರಾಣಿಗಳಿಗೆ ಬದುಕು ಕೊಡುವ ವರುಣನೊಳಗೆ ವಿಶೇಷ ವಿಭೂತಿಯಾಗಿ ಭಗವಂತ ತುಂಬಿದ. ಇಲ್ಲಿ\nಬರುವ ಭಗವಂತನ ವಿಭೂತಿನಾಮ ವರುಣಃ. ಹಿರಿದಾದ ಆನಂದ ಸ್ವರೂಪನಾದ್ದರಿಂದ “ವರುಣ' ಎನ್ನಿಸಿ\nವರುಣನಲ್ಲಿದ್ದು, ಅವನಿಗೆ ಜಲಚರಗಳ ಒಡೆತನವಿತ್ತ ಭಗವಂತ 'ವರುಣಃ'.\n\nಭೂಮಿಯಿಂದ ದೇಹತ್ಯಾಗ ಮಾಡಿ ಹೋಗುವ ಜೀವಗಳನ್ನು ನಿಯಂತ್ರಿಸುವ ದೇವತಾ ಶಕ್ತಿ-ಪಿತೃದೇವತೆಗಳು.\nಅವರಲ್ಲಿ ಅವರ ಮುಖಂಡನಾದ, ದ್ವಾದಶಾದಿತ್ಯರಲ್ಲಿ ಒಬ್ಬನಾದ ಅರ್ಯಮನಲ್ಲಿ ಭಗವಂತ ವಿಶೇಷ ಶಕ್ತಿಯಾಗಿ\nನಿಂತ. . “ಅರಿಯಬೇಕಾದವನು(ಅರ್ಯ) ಮತ್ತು ಅರಿತವನು(ಮಾ) ಆದ್ದರಿಂದ \"ಅರ್ಯಮನ್‌' ಎನ್ನಿಸಿ,\nಪಿತೃಪತಿಯಾದ ಅರ್ಯಮನೆಂಬ ಆದಿತ್ಯನಲ್ಲಿದ್ದೇನೆ” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.\n\nಪಾಪ ಮಾಡಿದ ಜೀವಗಳನ್ನು ನಿಯಂತ್ರಿಸುವವ ಯಮ. ಯಮನೊಳಗೆ ಭಗವಂತನ ವಿಶೇಷ ಸನ್ನಿಧಾನವಿದೆ.\nಯಮನಲ್ಲಿದ್ದು ನಿಯಮಿಸುವ ಭಗವಂತ “ಯಮಃ. ಯೋಗಶಾಸ್ತ್ರದಲ್ಲಿ ಯಮ ಎನ್ನುವ ಪದವನ್ನು ವಿಶಿಷ್ಟ\nಅರ್ಥದಲ್ಲಿ ಬಳಸಿದ್ದಾರೆ. ಅದು ನಾವು ಮಾಡಬಾರದ ಐದು ನಿಯಮಗಳನ್ನು ಹೇಳುತ್ತದೆ. (೧) ಹಿಂಸೆ, (೨) ಸುಳ್ಳು\nಹೇಳುವುದು,(೩) ಕದಿಯುವುದು,(೪) ಅತಿಯಾದ ಕಾಮ ಮತ್ತು (೫) ಇನ್ನೊಬ್ಬರ ಮುಂದೆ ಕೈಚಾಚುವುದು.\nಭಗವಂತನ ಉಪಾಸನೆಯ ಮಾರ್ಗದಲ್ಲಿ ಬಿಡಬೇಕಾದ ಈ ಐದು ನಿಯಮಗಳನ್ನು ಕೊಟ್ಟ ಭಗವಂತ ಯಮಃ.\nಇಡೀ ಜಗತ್ತನ್ನು ನಿಯಂತ್ರಿಸುವ, ಯಮಧರ್ಮನನ್ನೂ ನಿಯಂತ್ರಿಸುವ ಭಗವಂತ ಯಮಃ.\n",
  "10.30": "ಪ್ರಹ್ಲಾದಃ ಚ ಅಸ್ಮಿ ದೈತ್ಯಾನಾಮ್‌ ಕಾಲಃ ಕಲಯತಾಮ್‌ ಅಹಮ್‌ |\n\nಮೃಗಾಣಾಮ್‌ ಚ ಮೃಗೇಂದ್ರಃ ಅಹಮ್‌ ವೈನತೇಯ; ಚ ಪಕ್ಷಿಣಾಮ್‌ -ದಿತಿಯ ವಂಶದವರಲ್ಲಿ ಹಿರಿಯನಾದ\nಪ್ರಹ್ಲಾದ ನಾನು (ಹಿರಿಯ ಆನಂದದಿಂದ “ಪ್ರಹ್ಲಾದ' ಎನ್ನಿಸಿ ಪ್ರಹ್ಲಾದನಲ್ಲಿದ್ದೇನೆ.] ಲೆಕ್ಕಿಗರಲ್ಲಿ ಕಾಲ ನಾನು.\n[ಕೊಲ್ಲುವವನಾದ್ದರಿಂದ “ಕಾಲ” ಎನ್ನಿಸಿ ಕಾಲದೇವತೆಯಲ್ಲಿದ್ದೇನೆ.] ಮೃಗಗಳಲ್ಲಿ ಸಿಂಹ ನಾನು.\n\n[ಮೃಗ:ಭಗವಂತನನ್ನರಸುವ ಭಕ್ತರಿಗೆ, ಇಂದ್ರ ನಒಡೆಯನಾದ್ದರಿಂದ \"ಮೃಗೇಂದ್ರ' ಎನ್ನಿಸಿ ಸಿಂಹದಲ್ಲಿದ್ದೇನೆ.]\nಹಕ್ಕಿಗಳಲ್ಲಿ ಗರುಡ ನಾನು. [ವಿನತ :ಶರಣಾದವರಿಗೆ ಆಸರೆಯಾಗಿ “ವೈನತೇಯ' ಎನ್ನಿಸಿ ಗರುಡನಲ್ಲಿದ್ದೇನೆ.]\n\nಭಗವಂತನ ಸನ್ನಿಧಾನ ಸಜ್ಜನರಲ್ಲೂ ಇದೆ, ದುರ್ಜನರಲ್ಲೂ ಇದೆ. ದೈತ್ಯರಿಗೆ ಬಲವನ್ನು ಕೊಡುವವನೂ\nಭಗವಂತ. ಸಾಮಾನ್ಯವಾಗಿ ದೈತ್ಯರು ಇನ್ನೊಬ್ಬರ ಬದುಕನ್ನು ಹಾಳುಗೆಡುವವರು. ಆದರೆ ಇಂತಹ\nದೈತ್ಯವಂಶದ ಆದಿಯಲ್ಲಿ ಹುಟ್ಟಿದ ಪ್ರಹ್ಲಾದ-ಎಲ್ಲರಿಗಿಂತ ಭಿನ್ನ. ಇದಕ್ಕೆ ಕಾರಣ ಭಗವಂತ ಈತನಲ್ಲಿ\nವಿಶೇಷವಾಗಿ ಸನ್ನಿಧಾನವಿತ್ತಿರುವುದು. ದೈತ್ಯ ವಂಶದಲ್ಲಿ ಹುಟ್ಟಿ, ಆ ಸ್ವಭಾವದಿಂದ ಕಳಚಿಕೊಂಡು ಬಹಳ\nಎತ್ತರಕ್ಕೇರಿದವ ಪ್ರಹ್ಲಾದ. ಈ ಕಾರಣದಿಂದ ದೈತ್ಯರಲ್ಲೇ ವಿಶೇಷ ವಿಭೂತಿ ಈತ. ಪ್ರಹ್ಲಾದನ ಮೇಲೆ\nಭಗವಂತನ ವಿಶೇಷ ಅನುಗ್ರಹ. ಆತ ಗರ್ಭದಲ್ಲಿದ್ದಾಗಲೇ ಆತನಿಗೆ ದೇವರ್ಷಿ ನಾರದರ ಮೂಲಕ ಅಧ್ಯಾತ್ಮ\nಉಪದೇಶ ಪಡೆಯುವ ಭಾಗ್ಯ ದೊರೆಯಿತು. ಈತ ಧ್ರುವನಂತೆ ತನ್ನ ಐದನೇ ವಯಸ್ಸಿನಲ್ಲಿ ದೇವರನ್ನು ಕಂಡ\nಸಾಧಕ. ಪ್ರಹ್ಲಾದನ ಮುಖೇನ ಪ್ರಪಂಚಕ್ಕೆ ಭಗವಂತ ಬಹಳ ಮುಖ್ಯವಾದ ಸಂದೇಶವನ್ನು ನೀಡಿದ್ದಾನೆ.\n“ಭಗವಂತ ಭಯಾನಕ ಅಲ್ಲ, ಪ್ರೀತಿಯಿಂದ ಭಗವಂತನ ಬಳಿಗೆ ಹೋದರೆ ಆತ ನಮ್ಮನ್ನು ಅಷ್ಟೇ ಪ್ರೀತಿಯಿಂದ\nಕಾಣುತ್ತಾನೆ; ಭಗವಂತನ ಪೂಜೆ. ಒಂದು ವ್ಯಾಪಾರವಲ್ಲ, ನಮ್ಮ ಯಾವುದೋ ಬಯಕೆಯನ್ನು\nಸಾಧಿಸಿಕೊಳ್ಳುವುದಕ್ಕೋಸ್ಕರ ನಾವು ದೇವರ ಪೂಜೆ ಮಾಡಬಾರದು; ನಮ್ಮ ನಿಷ್ಕಾಮ ಭಕ್ತಿ ಭಗವಂತನಿಗೆ\nಇಷ್ಟ; ಈ ರೀತಿ ಭಗವಂತನನ್ನು ಪೂಜಿಸುವುದರಿಂದ ನಾವು ಸದಾ ಆನಂದದಿಂದಿರಬಹುದು' ಎನ್ನುವ ಸತ್ಯವನ್ನು\nಪ್ರಹ್ಲಾದ ಪ್ರಪಂಚಕ್ಕೆ ತೋರಿಸಿಕೊಟ್ಟ. ಇಲ್ಲಿ ಬರುವ ಭಗವಂತನ ವಿಭೂತಿನಾಮ ಪ್ರಹ್ಲಾದಃ. ಎಂದೂ\nದುಃಖವಿಲ್ಲದ ಪೂರ್ಣವಾದ ಆನಂದಮೂರ್ತಿ ಭಗವಂತ ಪ್ರಹ್ಲಾದಃ.\n\nಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಕಾಲಃ ಕಲಯತಾಮ್‌ ಅಹಮ್‌” ಎಂದು. ಈ ಜಗತ್ತಿನಲ್ಲಿ ಅನಾಧಿ ಅನಂತ ಕಾಲದಲ್ಲಿ\nನಡೆಯತಕ್ಕ ಪ್ರತಿಯೊಂದು ಹುಟ್ಟು-ಸಾವು ಪೂರ್ವನಿಶ್ಚಿತ. ಇದನ್ನು ಬದಲಿಸಲು ಯಾರಿಂದಲೂ ಸಾಧ್ಯವಿಲ್ಲ. ಇಲ್ಲಿ\nಕಾಲ ಎನ್ನುವ ಪದ ಲೆಕ್ಕ, ಮೃತ್ಯು, ಶಿವ, ದುರ್ಗೆ, ಕಾಲಾಗ್ನಿ, ಇತ್ಯಾದಿ ಅನೇಕ ಅರ್ಥವನ್ನು ಕೊಡುತ್ತದೆ.\nಇವೆಲ್ಲದರಲ್ಲೂ ಭಗವಂತನ ವಿಶೇಷ ವಿಭೂತಿ ಅಡಗಿದೆ. ಭಗವಂತ ಕಾಲಃ ನಾಮಕನಾಗಿ “ಕಾಲ”ದಲ್ಲಿ\nತುಂಬಿದ್ದಾನೆ. ಕಾಲ ಎನ್ನುವುದು 'ಕಲ' ಎನ್ನುವ ಧಾತುವಿನಿಂದ ಬಂದ ಪದ. ಎಲ್ಲಾ ಗುಣಗಳನ್ನು, ಎಲ್ಲಾ\nಸಾಮರ್ಥ್ಯವನ್ನು ತನ್ನೊಳಗೆ 'ಕಲೆ' ಹಾಕಿದವನು ಕಾಲಃ. ಭಗವಂತ ಸಮಸ್ತ ಸದ್ಗುಣಗಳಿಂದ ಪರಿಪೂರ್ಣವಾದ\nತತ್ವ. ಈ ತತ್ವವನ್ನು ನಾವು ಅರಿಯದೇ ಅಹಂಕಾರಿಗಳಾದಾಗ, ಅದೇ ತತ್ವ 'ಕಾಲ ಪುರುಷನಾಗಿ' ನಮ್ಮ\nಸಂಹಾರಕ್ಕೆ ಕಾರಣವಾಗುತ್ತದೆ. ನಮ್ಮ ಉದ್ಧಾರ ಕೆಲವೊಮ್ಮೆ 'ಬದುಕಿನಲ್ಲಿ'ದ್ದರೆ ಇನ್ನು ಕೆಲವೊಮ್ಮೆ ನಮ್ಮ\n'ಸಾವಿನಲ್ಲಿ'; ಕೆಲವೊಮ್ಮೆ ನಮ್ಮ 'ಮಾನದಲ್ಲಿ', ಇನ್ನು ಕೆಲವೊಮ್ಮೆ ನಮ್ಮ 'ಅವಮಾನದಲ್ಲಿ'.; ಕೆಲವೊಮ್ಮೆ ನಮ್ಮ\n'ಜ್ಞಾನದಲ್ಲಿ' ನಮ್ಮ ಉದ್ಧಾರವಿದ್ದರೆ, ಇನ್ನು ಕೆಲವೊಮ್ಮೆ ನಮ್ಮ 'ಅಜ್ಞಾನದಲ್ಲಿ' ನಮ್ಮ ಉದ್ಧಾರವಿರುತ್ತದೆ. ಆದರೆ\nನಮ್ಮ 'ಅಹಂಕಾರದಲ್ಲಿ' ಎಂದೆಂದೂ ಉದ್ಧಾರವಿಲ್ಲ. ಜಗತ್ತಿನಲ್ಲಿ ಅಹಂಕಾರ ಭರಿತ ಅಜ್ಞಾನ ತುಂಬಿದಾಗ\nಭಗವಂತ 'ಕಾಲ ಪುರುಷನಾಗಿ' ಬೆಳೆದು ನಿಲ್ಲುತ್ತಾನೆ. ಕಾಲ ಎನ್ನುವುದಕ್ಕೆ ಇನ್ನೊಂದು ಅರ್ಥ 'ಸಮಯ'.\nಪ್ರತಿಯೊಂದು ಕ್ರಿಯೆಯ ಹಿಂದೆ 'ಕಾಲ' ಸರ್ವ ಕಾರಣವಾಗಿರುತ್ತದೆ. ಕಾಲನಿಯಾಮಕ ಭಗವಂತ ಕಾಲಃ.\n\nಜ್ಞಾನಕಾರಕವಾದ ಅವತಾರಗಳಿಂದ (ವ್ಯಾಸ,ಕಪಿಲ,ದತ್ತಾತ್ರಯ, ನರ-ನಾರಾಯಣ, ಇತ್ಯಾದಿ) ಅಜ್ಞಾನಕ್ಕೆ\n\n'ಕಾಲವಾದ' ಭಗವಂತ, ಬಲಕಾರಕ ಅವತಾರಗಳಿಂದ(ನರಸಿಂಹ, ವರಾಹ, ರಾಮ,ಪರಶುರಾಮ, ಇತ್ಯಾದಿ)\nಅಹಂಕಾರಕ್ಕೆ 'ಕಾಲನಾದ'\". ಹೀಗೆ ಸರ್ವ ಗುಣಪೂರ್ಣ, ಸರ್ವ ಸಂಹಾರಕ ಹಾಗೂ ಕಾಲನಿಯಾಮಕ ಭಗವಂತ\nಕಾಲಃ.\n\nಸಂಹಾರ ಶಕ್ತಿಯಾಗಿ ತನ್ನ ವಿಭೂತಿಯನ್ನು ಹೇಳಿದ ಕೃಷ್ಣ, ಮುಂದೆ ಪ್ರಾಣಿಗಳಲ್ಲಿ ಬಹಳ ಉಗ್ರ ಮತ್ತು ಬಲಿಷ್ಠ\nಪ್ರಾಣಿಯಲ್ಲಿ ತನ್ನ ವಿಭೂತಿಯನ್ನು ವಿವರಿಸುತ್ತಾನೆ. ಭೂಮಿಯಲ್ಲಿ ಹೆಚ್ಚು ಬಲಿಷ್ಠ ಮತ್ತು ದೊಡ್ಡ ಪ್ರಾಣಿ ಆನೆ. ಆದರೆ\nಇಂತಹ ಆನೆಯನ್ನೂ ಕೂಡಾ ಸಂಹಾರ ಮಾಡಬಲ್ಲ ಕಾಡಿನ ರಾಜ ಮೃಗೇಂದ್ರ-ಸಿಂಹ. ಮೃಗಗಳಲ್ಲೇ ಶ್ರೇಷ್ಠ\nಮೃಗ ಎನ್ನಿಸಿಕೊಳ್ಳುವ ವಿಭೂತಿಯಾಗಿ ಭಗವಂತ ಸಿಂಹದಲ್ಲಿ ಕೂತ. ಇಲ್ಲಿ ಬರುವ ಭಗವಂತನ ನಾಮ\n\"ಮೃಗೇಂದ್ರಃ. ಭಗವಂತನ ಸಾಧನೆಯಲ್ಲಿ ನಿಂತವರಿಗೆ ಮಾರ್ಗದರ್ಶಕನಾಗಿ ನಿಲ್ಲುವ(ಮೃಗ) ಸರ್ವಶ್ರೇಷ್ಠ\nಭಗವಂತ “ಮೃಗೇಂದ್ರಃ'.\n\nಪ್ರಾಣಿಯ ನಂತರ ಪಕ್ಷಿಗಳಲ್ಲಿ ಭಗವಂತನ ವಿಭೂತಿ. ಪಕ್ಷಿಗಳಲ್ಲೇ ಅತ್ಯಂತ ಶ್ರೇಷ್ಠ ಪಕ್ಷಿ 'ಗರುಡ'. ಹೊಟ್ಟೆಯ\nಭಾಗ ಬೆಳ್ಳಗಿರುವ ಹದ್ದಿನ ಜಾತಿಯ ಪಕ್ಷಿ ಗರುಡ. ಭಗವಂತನ ವಾಹನ ಗರುಡ ವಿನುತೆಯ ಮಗ. ಆದ್ದರಿಂದ\nಈತನನ್ನು ವೈನತೇಯ ಎನ್ನುತ್ತಾರೆ. ತನಗೆ ಶರಣಾಗುವ ಭಕ್ತರಿಗೆ(ವಿನತ) ಆಸರೆಯಾಗಿ “ವೈನತೇಯ' ಎನ್ನಿಸಿ\nಭಗವಂತ ಗರುಡನಲ್ಲಿ ಸನ್ನಿಹಿತನಾಗಿದ್ದಾನೆ. ಭಗವಂತನನ್ನು ತನ್ನ ಹೆಗಲ ಮೇಲೆ ಹೊತ್ತು ಓಡಾಡುವ ಗರುಡ-\nಭಗವಂತನ ವಿಶೇಷ ವಿಭೂತಿ.\n",
  "10.31": "ಪವನಃ ಪವತಾಮ್‌ ಅಸ್ಮಿ ರಾಮಃ ಶಸ್ತ್ರಭೃತಾಮ್‌ ಅಹಮ್‌ ।\n\nರುಷಾಣಾಮ್‌ ಮಕರ; ಚ ಅಸ್ಮಿ ಸ್ರೋತಸಾಮ್‌ ಅಸ್ಮಿ ಜಾಹ್ನವೀ-ಚಲಿಸುವ ವಸ್ತುಗಳಲ್ಲಿ ಮಿಗಿಲಾದ ಗಾಳಿ\nನಾನು.[ಪಂಜಗತ್ತನ್ನು. ಪಾಲಿಸುವ ದೇವತೆಗಳಿಂದಲೂ, ವನ್ಪಸೇವ್ಯನಾದ್ದರಿಂದ 'ಪವನ' ಎನ್ನಿಸಿ\nಗಾಳಿಯಲ್ಲಿದ್ದೇನೆ.] ಆಯುಧದಿಂದ ಹೋರಾಡಬಲ್ಲ ವೀರರಲ್ಲಿ. ನಾನು [ರಂಆನಂದರೂಪನಾಗಿ,\nಅಮ-ಅಪರಿಮಿತನಾದ್ದರಿಂದ ಮತ್ತು ಲೋಕವನ್ನು ರಮಿಸುವುದರಿಂದ] ರಾಮನೆಂದು ಹೆಸರಾಗಿದ್ದೇನೆ.\nಮೀನುಗಳಲ್ಲಿ ತಿಮಿಂಗಿಲ ನಾನು. [ಮಾತಿಳಿವನ್ನು, ಕರಂಕೊಡುವವನಾದ್ದರಿಂದ “ಮಕರ' ಎನ್ನಿಸಿ\nಮಕರದಲ್ಲಿದ್ದೇನೆ.] ನದಿಯಲ್ಲಿ ಗಂಗೆ ನಾನು. [ಜಹತ್‌ ಕಾಮನೆಗಳನ್ನು ತೊರೆದವರಿಗೆ, ಅವಿ-ರಕ್ಷಕನಾಗಿ,\n'ಜಾಹ್ನವಿ' ಎನ್ನಿಸಿ ಗಂಗೆಯಲ್ಲಿದ್ದೇನೆ.]\n\nಮುಂದುವರಿದು ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ಪವನಃ ಪವತಾಮಸ್ಮಿ” ಎಂದು. 'ಪವನ' ಎನ್ನುವ ಪದದ ಪ್ರಸಿದ್ಧವಾದ\nಅರ್ಥ 'ಗಾಳಿ' ಅಥವಾ ವಾಯುದೇವರು. ಆಕಾಶದಲ್ಲಿ ಸಂಚರಿಸುವ ಶಕ್ತಿಗಳಲ್ಲೇ ದೊಡ್ಡ ವಿಭೂತಿ “ವಾಯು'. ನಮ್ಮ\nಜೀವವನ್ನು ನಿಯಂತ್ರಿಸುವ ವಾಯುದೇವರಲ್ಲಿ ವಿಶೇಷವಾಗಿ ಸನ್ನಿಹಿತನಾಗಿರುವ ಭಗವಂತ ಪವನಃ. ಪವತೇ\n\nಇತಿ ಪವನಃ - ಅಂದರೆ ನಿರಂತರ ಚಲಿಸುವಂತಾದ್ದು. ಎಲ್ಲರ ಒಳಗೂ ಅಂತರ್ಯಾಮಿಯಾಗಿರುವ ಭಗವಂತ,\n\nಆಯಾ ವಸ್ತುವಿನಲ್ಲಿ ಆಯಾ ರೂಪದಲ್ಲಿದ್ದು ನಿರಂತರ ಚಲನೆ ಕೊಡುತ್ತಿರುತ್ತಾನೆ. ನಮ್ಮ ದೇಹದಲ್ಲಿ ಆತನ ಚಲನೆ\nನಿಂತಾಕ್ಷಣ ನಾವು 'ಶವ' ವಾಗುತ್ತೇವೆ. ಉಪನಿಷತ್ತಿನಲ್ಲಿ ಭಗವಂತನನ್ನು ವನಃ ಎಂದಿದ್ದಾರೆ. ಅವನು ಪ-ವನಃ;\nಇಲ್ಲಿ 'ಪ' ಎಂದರೆ 'ಪಾಲನೆ'. ನಮ್ಮನ್ನು ಹಾಗೂ ಸಮಸ್ತ ಬ್ರಹ್ಮಾದಿ ದೇವತೆಗಳನ್ನು ಪಾಲಿಸುವ ಶಕ್ತಿ. ವನಃ\nಎಂದರೆ ಎಲ್ಲರೂ ಭಜಿಸಬೇಕಾದ, ಪ್ರೀತಿಯಿಂದ ಉಪಾಸನೆ ಮಾಡತಕ್ಕಂತಹ, ಎಲ್ಲರೂ ಆಶ್ರೈಸಬೇಕಾದ ವಸ್ತು.\nಸಹಸ್ರ ರೂಪನಾಗಿ ಸಹಸ್ರ ಜೀವರಲ್ಲಿ ನೆಲೆಸಿ, ನಿರಂತರ ಪಾಲಿಸುವ ಭಗವಂತ ಪವನಃ.\n\n“ಆಯುಧವನ್ನು ಹಿಡಿದು ಹೋರಾಡಬಲ್ಲ ವೀರರಲ್ಲಿ ರಾಮ ನಾನು” ಎಂದು ತನ್ನ ಸ್ವರೂಪ ವಿಭೂತಿಯನ್ನು\nವಿವರಿಸುತ್ತಾನೆ. ಕೃಷ್ಣ... ಭಗವಂತನ ಇತರ ಎಲ್ಲಾ ಅವತಾರಕ್ಕಿಂತ ರಾಮಾವತಾರದಲ್ಲಿ ಆತ\nಕೋದಂಡಪಾಣಿಯಾಗಿ ಶಸ್ತ್ರದ ಪೂರ್ಣ ಬಳಕೆ ಮಾಡಿ ಶತ್ರು ನಿಗ್ರಹ ಮಾಡಿದ.\n\nರಾಮ ಎನ್ನು ವ. ನಾಮಕ್ಕೆ ಶಾಸ್ತ್ರದಲ್ಲಿ ಅನೇಕ ಅರ್ಥಗಳನ್ನು ಕಾಣಬಹುದು. 'ರಾ-ಅಮಃ, ಎಂದರೆ\nಅಪರಿಮಿತವಾದ ಆನಂದಸ್ವರೂಪ ಹಾಗೂ ಎಲ್ಲರಿಗೂ ಆನಂದವನ್ನು ಹಂಚುವವನು. ಭಗವಂತನ ಈ ಗುಣ\nರಾಮಾವತಾರದಲ್ಲಿ ಸ್ಪಷ್ಟವಾಗಿ ಕಾಣಸಿಗುತ್ತದೆ. ರಾಮಾವತಾರದಲ್ಲಿ ಭಗವಂತ ಎಲ್ಲಿಯೂ ಇನ್ನೊಬ್ಬರಿಗೆ\nನೋವಾಗುವಂತೆ ನಡೆದುಕೊಂಡಿಲ್ಲ. ತನ್ನನ್ನು ಕಾಡಿಗೆ ಕಳುಹಿಸಲು ಕಾರಣಕರ್ತೆಯಾದ ಕೈಕೇಯಿಯ ಮೇಲೆ\nಎಲ್ಲರು ಕೋಪಗೊಂಡಾಗಲೂ ಸಹ, ರಾಮಚಂದ್ರ ಒಮ್ಮೆಯೂ ಕೂಡಾ ಕೆಟ್ಟ ಮಾತನ್ನು ಆಡಲಿಲ್ಲ. ಬದಲಿಗೆ\n\"ನನ್ನಿಂದೇನಾದರೂ ಅಪರಾಧವಾಗಿದ್ದರೆ ಕ್ಷಮಿಸು” ಎಂದು ಹೇಳಿ ಸಂತೋಷದಿಂದ ಕಾಡಿಗೆ ಹೊರಟು ಹೋದ.\nಹೀಗೆ ಇನ್ನೊಬ್ಬರ ಸಂತೋಷಕ್ಕಾಗಿ ತ್ಯಾಗಮಾಡಿ ತೋರಿಸಿದ ಅಪೂರ್ವ ಅವತಾರ ರಾಮಾವತಾರ. ರಮೆಯ\nಅರಸಾದ ಸೀತಾಪತಿ ಭಗವಂತ, ಈ ಅವತಾರದಲ್ಲಿ ಗಂಡು-ಹೆಣ್ಣಿನ ನಡುವೆ ದಾಂಪತ್ಯ ಜೀವನ ಹೇಗಿರಬೇಕು,\nಅಣ್ಣ-ತಮ್ಮಂದಿರ ಪ್ರೀತಿ ಹೇಗಿರಬೇಕು, ತಂದೆ-ತಾಯಿ-ಮಕ್ಕಳ ಬಾಂಧವ್ಯ ಹೇಗಿರಬೇಕು ಎನ್ನುವುದನ್ನು ಸ್ವಯಂ\nತೋರಿಸಿ ಕೊಟ್ಟಿದ್ದಾನೆ. ಇದು ಜಗತ್ತಿಗೆ ಆನಂದ ಕೊಟ್ಟ ಭಗವಂತನ ಅಮಿತಾನಂದಸ್ವರೂಪ ವಿಭೂತಿ.\nನೀರಿನಲ್ಲಿರುವ ಮೀನುಗಳಲ್ಲೇ ಅತ್ಯಂತ ಶಕ್ತಿಶಾಲಿ ಮತ್ತು ಅತ್ಯಂತ ದೊಡ್ಡ ಆಕಾರವುಳ್ಳದ್ದು ತಿಮಿಂಗಿಲ. ಕೃಷ್ಣ\nಹೇಳುತ್ತಾನೆ “ರುಷಾಣಾಂ ಮಕರಶ್ಚಾಸ್ಮಿ” ಎಂದು. ಇಲ್ಲಿ ಮಕರ ಎಂದರೆ ತಿಮಿಂಗಿಲ. ಭಗವಂತ ಮಕರ;\nಶಬ್ದವಾಚ್ಯನಾಗಿ ತಿಮಿಂಗಿಲನಲ್ಲಿ ವಿಶೇಷ ವಿಭೂತಿಯಾಗಿ ಅದಕ್ಕೆ ಆ ಶಕ್ತಿಯನ್ನು ಕೊಟ್ಟ. ತಿಳಿವನ್ನು(ಮ)\nಕೊಡುವ(ಕರ) ಭಗವಂತ ಮಕರಃ.\n\n“ನದಿಗಳಲ್ಲಿ ಗಂಗೆ ನಾನು” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ನದಿಗಳಲ್ಲೇ ಶ್ರೇಷ್ಠ-ಗಂಗೆ. ಈ ನದಿ ನೀರಿಗೆ ಸಾಟಿಯಾದ ಔಷಧ\nಇನ್ನೊಂದಿಲ್ಲ. ಗಂಗೆಯಲ್ಲಿ ಮಿಂದರೆ ನಾವು ನಮ್ಮ ಮನಃ ಶುದ್ಧಿ ಮಾಡಿಕೊಳ್ಳಬಹುದು. ಅಲ್ಲಿರುವ ಯಾವುದೇ\nಕೊಳೆ ನಮಗಂಟದು. ಶೇಖರಿಸಿಟ್ಟರೆ ಎಂದೂ ಕೆಡದ ನೀರು ಗಂಗೆ. ಗಂಗೆಗೆ ಈ ಮಹಾನ್‌ ಶಕ್ತಿಯನ್ನು ಕೊಟ್ಟ\nಭಗವಂತನ ವಿಭೂತಿನಾಮ “'ಜಾಹ್ನವಿ'. “ಜಹ್ನು' ಅಂದರೆ ತೊರೆಯುವುದು. ಕ್ಷುದ್ರ ಭೌತಿಕ ಬಯಕೆಗಳನ್ನು\nತೊರೆದು, ಭಗವಂತನ ಮಾರ್ಗದಲ್ಲಿ ಸಾಗುವವರ ರಕ್ಷಣೆ ಮಾಡುವ ಭಗವಂತ “ಜಾಹ್ನವಿ'. ಇದು ಭಗವಂತನ\nಸ್ತ್ರೀರೂಪ ಪ್ರತೀಕ ನಾಮ. ತಾಯಿಯಂತೆ ಸಲಹುವ ಭಗವಂತನನ್ನು ಸ್ತ್ರೀ ರೂಪದಲ್ಲಿ ಕೂಡಾ ಉಪಾಸನೆ\nಮಾಡುತ್ತಾರೆ. ಜಾಹ್ನವಿ ಭಗವಂತನ ಸ್ತ್ರೀರೂಪದ ನಾಮ.\n",
  "10.32": "ಸರ್ಗಾಹಾಮ್‌ ಆದಿಃ ಅಂತಃ ಚ ಮಧ್ಯಮ್‌ ಚ ಏವ ಅಹಮ್‌ ಅರ್ಜುನ |\n\nಅಧ್ಯಾತ್ಮವಿದ್ಯಾ ವಿದ್ಯಾನಾಮ್‌ ವಾದಃ ಪ್ರವದತಾಮ್‌ ಅಹಮ್‌.-ಓ ಅರ್ಜುನಾ, ಜೀವಿಗಳ ಹುಟ್ಟಿಗೆ, ಸಾವಿಗೆ,\nಇರವಿಗೆ ಕಾರಣ ನಾನು. ಅರಿವುಗಳಲ್ಲಿ ಅಧ್ಯಾತ್ಮದ ಅರಿವು ನಾನು. [ಜೀವರಿಗೆ ಒಡೆಯನಾದ್ದರಿಂದ \"ಅಧ್ಯಾತ್ಮ'\nಎನ್ನಿಸಿ, ಜ್ಞಾನರೂಪನಾದ್ದರಿಂದ 'ವಿದ್ಯಾ' ಎನ್ನಿಸಿ ಅಧ್ಯಾತ್ಮ ವಿದ್ಯೆಯಲ್ಲಿದ್ದೇನೆ.] ಚರ್ಚಿಸುವವರ ಚರ್ಚೆಯಲ್ಲಿ\n[ತತ್ವದ ತಿಳಿವಿಗಾಗಿ ನಡೆಸುವ] ವಾದ ನಾನು. [ಎಲ್ಲಾ ನಾಮಗಳಿಂದ ವಾಚ್ಯನಾಗಿ “ವಾದ' ಎನ್ನಿಸಿ\nವಾದದಲ್ಲಿದ್ದೇನೆ.]\n\nಪ್ರಪಂಚದಲ್ಲಿ ಇರುವ ಪ್ರತಿಯೊಂದು ವಸ್ತುವಿನಲ್ಲಿಯೂ ಭಗವಂತನ ವಿಭೂತಿ ಅಡಗಿದೆ. ನಮಗೆ ಮೇಲ್ನೋಟಕ್ಕೆ\nವ್ಯರ್ಥವೆಂದು ಕಾಣುವ ವಸ್ತುವಿನಲ್ಲೂ ಕೂಡಾ ಇನ್ನೊಂದು ವಸ್ತುವಿನಲ್ಲಿರದ ಒಂದು ವಿಶಿಷ್ಟಗುಣ(Exclusive Quality) ಅಡಗಿರುತ್ತದೆ. ಆದ್ದರಿಂದ ಒಂದು ಹುಲ್ಲುಕಡ್ಡಿಯಿಂದ ಹಿಡಿದು ಚತುರ್ಮುಖ ಬ್ರಹ್ಮನವರೆಗೆ ಎಲ್ಲವೂ\nಭಗವಂತನ ವಿಭೂತಿ. ಇಲ್ಲಿ ಕೃಷ್ಣ ಕೇವಲ ಆ ಗುಂಪಿನಲ್ಲಿ ವಿಶಿಷ್ಟಭೂತಿಯನ್ನು ಹೇಳಿದ್ದಾನೆ ಅಷ್ಟೆ. ಜೀವ ಹುಟ್ಟುವ\nಮೊದಲು ಇದ್ದವ, ಜೀವದ ಇರವಿಗೆ ಕಾರಣನಾದವ, ಕೊನೆಗೆ ಸಂಹಾರಶಕ್ತಿಯಾಗಿ ನಿಲ್ಲುವವ ಆ ಭಗವಂತ. ಹೀಗೆ\n“ಹುಟ್ಟುವಾಗ, ಇರುವಾಗ ಮತ್ತು ಅಂತದಲ್ಲೂ ನಾನಿದ್ದೇನೆ” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. “ಈ ವಿಷಯ-ಜ್ಞಾನಾರ್ಜನ\nಮಾಡಿದ, ಸಾತ್ವಿಕನಾದ, ನಿನಗೆ ತಿಳಿದೇ ಇದೆ” ಎನ್ನುವ ಅರ್ಥದಲ್ಲಿ ಕೃಷ್ಣ ಇಲ್ಲಿ ಪಾರ್ಥನನ್ನು 'ಅರ್ಜುನ' ಎಂದು\nವಿಶೇಷವಾಗಿ ಸಂಬೋಧಿಸಿದ್ದಾನೆ.\n\n“ಅರಿವುಗಳಲ್ಲಿ ಅಧ್ಯಾತ್ಮದ ಅರಿವು ನಾನು” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಭಗವಂತನನ್ನು ಸ್ಪರ್ಶಮಾಡುವ ಅಧ್ಯಾತ್ಮ\nವಿದ್ಯೆಯಲ್ಲಿ ಪರಮಾತ್ಮ ತುಂಬಿದ್ದಾನೆ. ಎಲ್ಲಾ ಆತ್ಮಗಳಿಗೆ ಹಿರಿದಾದ ಭಗವಂತ ಅಧಿಕ-ಆತ್ಮ(ಅಧ್ಯಾತ್ಮ).\nಅಧ್ಯಾತ್ಮ ವಿದ್ಯೆಯನ್ನು ಪಡೆಯಬೇಕಾದರೆ ನಾವು ಇನ್ನೊ ಬ್ಬರೊಂದಿಗೆ ಸಂವಾದ ಮಾಡಬೇಕು. ಇದು ನಮ್ಮ\nತಿಳುವಳಿಕೆಯನ್ನು ಹೆಚ್ಚಿಸಿಕೊಳ್ಳುವುದಕ್ಕಾಗಿ, ಜ್ಞಾನ ದಾಹವನ್ನು ಇಂಗಿಸಿಕೊಳ್ಳುವುದಕ್ಕಾಗಿ ಮಾಡುವ ಶಾಸ್ತ್ರೀಯ\nಚರ್ಚೆ. ಇಂತಹ ಚರ್ಚೆಯಲ್ಲಿ “ವಾದಃ' ಶಬ್ದವಾಚ್ಯನಾಗಿ ಭಗವಂತನಿರುತ್ತಾನೆ. ಎಲ್ಲಾ ನಾಮಗಳಿಂದ ವಾಚ್ಯನಾದ\nಭಗವಂತ ವಾದಃ.\n",
  "10.33": "ಅಕ್ಷರಾಣಾಮ್‌ ಅಕಾರಃ ಅಸ್ಮಿ ದ್ವಂದ್ವಃ ಸಾಮಾಸಿಕಸ್ಯ ಚ ।\nಅಹಮ್‌ ಏವ ಅಕ್ಷಯಃ ಕಾಲಃ ಧಾತಾ ಅಹಮ್‌ ವಿಶ್ವತೋಮುಖಃ -ಅಕ್ಷರಗಳಲ್ಲಿ ಮೊದಲ ಅಕಾರ ನಾನು. [\"ಅ'\nಎಂದು ಕರೆಸಿಕೊಂಡು, “ಅಕಾರ' ಎನ್ನಿಸಿ ಅ-ಕಾರದಿಂದ ವಾಚ್ಯನಾಗಿದ್ದೇನೆ.] ಸಮಾಸಗಳ ಗುಂಪಿನಲ್ಲಿ ದ್ವಂದ್ವ\n\nಸಮಾಸ ನಾನು. [ಎರಡು ರೂಪಗಳಿಂದ ಒಳಗೂ ಹೊರಗೂ ಇರುವುದರಿಂದ 'ದ್ವಂದ್ವ' ಎನ್ನಿಸಿ ದ್ವಂದ್ವ\nಸಮಾಸದಲ್ಲಿದ್ದೇನೆ.] ಅಳಿವಿರದ ನಾನೇ [ಕಾಲದಲ್ಲಿದ್ದು] ಕಬಳಿಸುವವನು. ಎಲ್ಲೆಡೆ ತುಂಬಿದ್ದು ಎಲ್ಲವನ್ನು\nಸಲಹುವವನೂ ನಾನೇ.\n\nಹಿಂದೆ ಶಬ್ದಗಳಲ್ಲಿ ಓಂಕಾರವನ್ನು ಹೇಳಿದ್ದ ಕೃಷ್ಣ, ಇಲ್ಲಿ ಅಕ್ಷರದಲ್ಲಿ ತನ್ನ ವಿಭೂತಿಯನ್ನು ಹೇಳುತ್ತಾ ಹೇಳುತ್ತಾನೆ:\n“ಅಕ್ಷರಾಣಾಮಕಾರೋಸ್ಮಿ” ಎಂದು. 'ಅ' ಪೂರ್ತಿಯಾಗಿ ಭಗವಂತನ ಎಲ್ಲಾ ಗುಣಗಳನ್ನೂ ಹೇಳುವ ವಿಶಿಷ್ಟ\nಅಕ್ಷರ. ಅ- ಅಂದರೆ “ಅಲ್ಲ'. ಭಗವಂತ 'ಅಲ್ಲ'. ಅಂದರೆ ನಮಗೆ ತಿಳಿದಿರುವ ಯಾವ ವಸ್ತುವೂ ಅವನಲ್ಲ. ಆತ\nಪ್ರಪಂಚದಿಂದ ವಿಲಕ್ಷಣ. ಇಂತಹ ಭಗವಂತ 'ಇಲ್ಲ'. ಅಂದರೆ ಆತನಲ್ಲಿ ಯಾವ ದೋಷವೂ ಇಲ್ಲ. ಆತ\nಸರ್ವಗುಣಪೂರ್ಣ. ಹೀಗೆ ಸರ್ವವಿಲಕ್ಷಣ, ಸರ್ವದೋಷದೂರ, ಸರ್ವಗುಣಪೂರ್ಣ ಭಗವಂತ ಅ-\nಕಾರವಾಚ್ಯನಾಗಿ “ಅ'ಕಾರದಲ್ಲಿ ತುಂಬಿದ್ದಾನೆ.\n\nಅಕ್ಷರದ ನಂತರ ಸಮಾಸಗಳ ಬಗ್ಗೆ ಹೇಳುತ್ತಾ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ದ್ವಂದ್ವಃ ಸಾಮಾಸಿಕಸ್ಯ” ಎಂದು. ನಮಗೆ\nತಿಳಿದಂತೆ ಯಾವುದೇ ಸಮಾಸವಾಗಬೇಕಾದರೆ ಅಲ್ಲಿ ಎರಡು ಶಬ್ದವಿರಬೇಕು (ಅಥವಾ ಒಂದು ಶಬ್ದ ಮತ್ತು\nಒಂದು ಪ್ರತ್ಯಯವಿರಬೇಕು). ಇತರ ಎಲ್ಲಾ ಸಮಾಸಗಳಲ್ಲಿ ಒಂದು ಪದ, ಅಥವಾ ಎರಡೂ ಪದ(ಬಹುವ್ರೀಹಿ)\nತನ್ನ ಪ್ರಾಧಾನ್ಯತೆಯನ್ನು ಕಳೆದುಕೊಳ್ಳಬಹುದು. ಆದರೆ ದ್ವಂದ್ವ ಸಮಾಸದಲ್ಲಿ ಎರಡೂ ಪದಗಳು ಮುಖ್ಯ.\nಉಭಯಪದ ಪ್ರಧಾನ ಸಮಾಸವಾದ ದ್ವಂದ್ವ ಸಮಾಸದಲ್ಲಿ ಭಗವಂತ ದ್ವಂದ್ವಃ ನಾಮಕನಾಗಿ ತುಂಬಿದ್ದಾನೆ.\nಎರಡು ರೂಪದಿಂದ ನಮ್ಮ ಒಳಗೂ-ಹೊರಗೂ ತುಂಬಿರುವ ಭಗವಂತ ದ್ವಂದ್ವಃ.\n\nಎಲ್ಲವನ್ನು ಸಂಹಾರ ಮಾಡುವ ಕಾಲಪುರುಷ ಭಗವಂತ, ಎಲ್ಲವನ್ನು ಧಾರಣೆ ಮಾಡಿ, ಪೋಷಣೆ ಮಾಡುವ\n'ಧಾತ'. ಇಂತಹ ಭಗವಂತ ವಿಶ್ವತೋಮುಖಃ. ಆತ ಎಲ್ದೆಡೆ ತುಂಬಿದ್ದಾನೆ. ಆತನಿಲ್ಲದ ತಾಣವಿಲ್ಲ. ಆತ ಕಾಣದ\nಎಡೆಯಿಲ್ಲ.\n",
  "10.34": "ಮೃತ್ಯುಃ ಸರ್ವ ಹರಃ ಚ ಅಹಮ್‌ ಉದ್ಭವಃ ಚ ಭವಿಷ್ಯತಾಮ್‌ ।\n\nಕೀರ್ತಿಃ ಶ್ರೀಃ ವಾಕ್‌ ಚ ನಾರೀಣಾಂ ಸ್ಮೃತಿಃ ಮೇಧಾ ಧೃತಿಃ ಕ್ಷಮಾ -ಎಲ್ಲವನ್ನೂ ಕಬಳಿಸುವ ಮೃತ್ಯುದೇವತೆ\n[ಸಾಯಿಸುವವನಾದ್ದರಿಂದ \"ಮೃತ್ಯು'ನಾಮಕನಾಗಿ, ಯಮನ ಪರಿವಾರ ದೇವತೆಯಾದ ಮೃತ್ಯುವಿನಲ್ಲಿದ್ದು\nಅವನಿಗೆ ಎಲ್ಲವನ್ನೂ ಕಬಳಿಸುವ ಶಕ್ತಿಯಿತ್ತವನು] ನಾನು. ಮುಂದೆ ಆಗುವವರನ್ನು ಹುಟ್ಟಿಸುವವನೂ ನಾನು.\nಹೆಂಗಸರಲ್ಲಿ ಕೀರ್ತಿಯ ದೇವತೆ ನಾನು; ಶ್ರೀದೇವಿ ನಾನು; ವಾಗ್ದೇವಿ ನಾನು. ಸ್ಮರಣಶಕ್ತಿಯ ದೇವತೆ ನಾನು;\nಧಾರಣಶಕ್ತಿಯ ದೇವತೆ ನಾನು; ಸಹನೆಯ ದೇವತೆ ಸಾನು; ಕ್ಷಮಾ ದೇವಿ ನಾನು.[ಕೀರ್ತನೀಯವಾಗಿ 'ಕೀರ್ತಿ'\nಎನ್ನಿಸಿ ಕೀರ್ತಿದೇವಿಯಲ್ಲಿದ್ದೇನೆ; ಆಶ್ರಯನಾಗಿ 'ಶ್ರೀ' ಎನ್ನಿಸಿ ಶ್ರೀದೇವಿಯಲ್ಲಿದ್ದೇನೆ; ವಕ್ತಾರನಾಗಿ “ವಾಕ್‌' ಎನ್ನಿಸಿ\nವಾಗ್ದೇವಿಯಲ್ಲಿದ್ದೇನೆ; ಸ್ಮರಣೀಯನಾಗಿ 'ಸ್ಮೃತಿ' ಎನ್ನಿಸಿ ಸ್ಮೃತಿದೇವಿಯಲ್ಲಿದ್ದೇನೆ; ಅರಿವಿನ ಮೂರ್ತಿಯಾಗಿ\n\n'ಧೃತಿ'. ಎನ್ನಿಸಿ. ಧೃತಿದೇವಿಯಲ್ಲಿದ್ದೇನೆ; ತಪ್ಪುಗಳನ್ನು. ಮನ್ನಿಸುವವನಾಗಿ “ಕ್ಷಮಾ” . ಎನ್ನಿಸಿ\nಕ್ಷಮಾದೇವಿಯಲ್ಲಿದ್ದೇನೆ.]\n\nಭಗವಂತ ಪ್ರಳಯಕಾಲದಲ್ಲಿ ಎಲ್ಲವನ್ನು ಕಬಳಿಸುವ ಮೃತ್ಯುದೇವತೆ ಕೂಡಾ ಹೌದು. ಪ್ರಳಯಕಾಲ ನಂತರ\nಸೃಷ್ಟಿಯನ್ನು ಪುನಃ ನಿರ್ಮಾಣ ಮಾಡುವವನೂ ಅವನೇ. ಸ್ತ್ರೀ ರೂಪದಲ್ಲಿನ ತನ್ನ ವಿಭೂತಿಯನ್ನು ಹೇಳುತ್ತಾ\nಕೃಷ್ಣ ಇಲ್ಲಿ ಮುಖ್ಯವಾಗಿ ಲಕ್ಷ್ಮಿ, ಸರಸ್ವತಿ ಮತ್ತು ಭಾರತಿಯರಲ್ಲಿ ತನ್ನ ವಿಭೂತಿಯನ್ನು ವಿವರಿಸಿದ್ದಾನೆ. ಕೀರ್ತಿ,\nಅದೃಷ್ಟ, ಸುಂದರ ಮಾತು, ಸ್ಮರಣಶಕ್ತಿ, ಬುದ್ಧಿಶಕ್ತಿ, ದೃಢತೆ ಮತ್ತು ತಾಳ್ಮೆ -ಇವುಗಳ ಅಭಿಮಾನಿ ದೇವತೆಯರು\nಮುಖ್ಯವಾಗಿ ಲಕ್ಷ್ಮಿ, ಸರಸ್ವತಿ. ಮತ್ತು ಭಾರತಿಯರು. ಇವರಲ್ಲಿ ಸ್ತ್ರೀರೂಪ ವಿಭೂತಿಯಾಗಿ ಭಗವಂತ\nನಿಂತಿದ್ದಾನೆ.\n",
  "10.35": "ಬೃಹತ್ಸಾ ಮ ತಥಾ ಸಾಮ್ನಾ ಮ್‌ ಗಾಯತ್ರೀ ಛಂದಸಾಮ್‌ ಅಹಮ್‌ ।\n\nಮಾಸಾನಾಮ್‌ ಮಾರ್ಗಶೀರ್ಷಃ ಅಹಮ್‌ ಋತೂನಾಮ್‌ ಕುಸುಮಾಕರಃ -ಸಾಮದ ಗಾನಗಳಲ್ಲಿ ಬೃಹತ್‌\nಸಾಮವೆಂಬ ಗಾನ ನಾನು. [ಬೃಹತ್‌ ಐಹಿರಿದಾದ, ಸ-ಸಾರವಸ್ತು ಮತ್ತು, ಅಮ-ಅರಿವಿಗೆಟುಕದವನಾದ್ದರಿಂದ\n\"ಬೃಹತ್ಸಾಮ' ಎನ್ನಿ ಸಿ ಬೃಹತ್ಸಾಮವೆಂಬ ಗಾನದಲ್ಲಿದ್ದೇನೆ1. ಛಂದಸ್ಸುಗಳಲ್ಲಿ ಗಾಯತ್ರಿ ನಾನು. [ಗಾಯ\nಗಾಯಕರನ್ನು ತ್ರಿಎಸಲಹುವುದರಿಂದ “ಗಾಯತ್ತಿ' ಎನ್ನಿಸಿ ಗಾಯತ್ರಿ ಛಂದಸ್ಸಿನಲ್ಲಿದ್ದೇನೆ]. ತಿಂಗಳಲ್ಲಿ ಮಾರ್ಗಶಿರ\nನಾನು. [ದಾರಿಯ ಕೊನೆಯಲ್ಲಿರುವುದರಿಂದ “ಮಾರ್ಗಶೀರ್ಷ' ಎನ್ನಿಸಿ. ಮಾರ್ಗಶಿರಮಾಹದಲ್ಲಿದ್ದೇನೆ.]\nಋತುಗಳಲ್ಲಿ ವಸಂತ ನಾನು. [ಕು:ಕೆಟ್ಟ, ಸು- ಒಳ್ಳೆಯ, ಮಾ-ಅರಿವನ್ನು, ಕರ-ನೀಡುವುದರಿಂದ “ಕುಸುಮಾಕರ'\nಎನ್ನಿಸಿ ವಸಂತ ಋತುವಿನಲ್ಲಿದ್ದೇನೆ.]\n\nಸಾಮಗಾನದಲ್ಲಿ ಅನೇಕ ವಿಧ. ಸಪ್ತ ಸ್ವರವನ್ನು ಬಳಸಿ ಹಾಡುವುದು ಸಾಮವೇದದಲ್ಲಿ ಮಾತ್ರ. ಇದು ಋಗ್ವೇದ\nಯಜುರ್ವೇದದಲ್ಲಿ ಇಲ್ಲ. ಎಲ್ಲಾ ಸಾಮಗಳಲ್ಲಿ ಸಪ್ತಸ್ವರದ ಬಳಕೆ ಇಲ್ಲ. ಈ ರೀತಿ ಸಪ್ಪಸ್ವರವಿರುವ ಸಾಮದಲ್ಲಿ\n“ಬೃಹತ್ಸಾಮವೆಂಬ ಗಾನ ನಾನು” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಇಲ್ಲಿ ಬಂದಿರುವ ಭಗವಂತನ ನಾಮ \"ಬೃಹತ್ಸಾಮಃ' ಎ\nಹಿರಿದಾದ, ಸಾರಭೂತನಾದ ಮತ್ತು ನಮ್ಮ ಅರಿವಿಗೆಟುಕದೆ ಅಮಿತವಾಗಿರುವ ಭಗವಂತ “ಬೃಹತ್ಸಾಮಃ'.\n\nಪದ್ಯದ ರೂಪದಲ್ಲಿ ಒಂದು ಅಪೂರ್ವವಾದ ಅರ್ಥವನ್ನು, ಅಧ್ಯಾತ್ಮದ ಸಂದೇಶವನ್ನು ತುಂಬಿಡುವಂತಾದ್ದು-\nಛಂದಸ್ಸು. ಇದು ನಮ್ಮ ಅಭಿಪ್ರಾಯವನ್ನು ಲಯಬದ್ಧವಾಗಿ ವ್ಯಕ್ತಪಡಿಸುವ ವಿಧಾನ. ಛಂದಸ್ಸಿನಲ್ಲಿ ಪ್ರಧಾನವಾಗಿ\nಏಳು ಛಂದಸ್ಸುಗಳಿವೆ. 24 ಅಕ್ಷರದ ಗಾಯತ್ರಿ, 28 ಅಕ್ಷರದ ಉಶ್ಜಿಕ್‌, 32 ಅಕ್ಷರದ ಅನುಷ್ಟುಪ್‌, 36 ಅಕ್ಷರದ\nಬೃಹತೀ, 40 ಅಕ್ಷರದ ಪಂಕ್ತಿ, 44 ಅಕ್ಷರದ ತ್ರಿಷ್ಟುಪ್‌ ಮತ್ತು. 48 ಅಕ್ಷರದ ಜಗತೀ. ಈ ಛಂದಸ್ಸುಗಳಲ್ಲಿ\nಭಗವಂತನ ವಿಶೇಷ ವಿಭೂತಿ ಇರುವ ಛಂದಸ್ಸು 'ಗಾಯತ್ರಿ'. ಇದು ಭಗವಂತನ ಹೆಸರು ಕೂಡಾ ಹೌದು.\n\n'ಗಾಯತಂ ತ್ರಾಯತೆ ಇತಿ ಗಾಯತ್ರಿಃ. ಯಾರು ಭಗವಂತನನ್ನು ಈ ಮಂತ್ರದಿಂದ ಸ್ತೋತ್ರ ಮಾಡುತ್ತಾರೋ\nಅವರನ್ನು ಆತ ರಕ್ಷಣೆ ಮಾಡುತ್ತಾನೆ. ಗಾಯತ್ರಿ ಛಂದಸ್ಸು ಏಳು ಛಂದಸ್ಸುಗಳಲ್ಲಿ ಮೊದಲನೆಯದು. ಎಂಟು\nಅಕ್ಷರದ ಮೂರು ಪಾದಗಳುಳ್ಳ ಗಾಯತ್ರಿ ಎಲ್ಲದರ ಪಂಚಾಂಗ(Foundation)ದಂತಿದೆ. ಋಗ್ವೇದದಲ್ಲಿನ ಹೆಚ್ಚಿನ\nಮಂತ್ರಗಳು ಗಾಯತ್ರಿ ಛಂದಸ್ಸಿನಲ್ಲಿದೆ. ಸಮಸ್ತ ವೇದಗಳ 'ವೇದಮಾತ' ಎನ್ನಿಸಿಕೊಂಡಿರುವ ಗಾಯತ್ತಿ\nಮಂತ್ರವಿರುವುದು “ಗಾಯತ್ರಿ' ಛಂದಸ್ಸಿನಲ್ಲಿ. ಹೀಗೆ ಗಾಯತ್ರಿ ಇತರ ಛಂದಸ್ಸಿಗೆ ಮಾತೃಸ್ಥಾನೀಯವಾಗಿದೆ.\nಗಾಯತ್ರಿ. ಅಧ್ಯಾತ್ಮದ ಮೂಲಭೂತವಾದ ಮುಖವನ್ನು ಹೊಂದಿರತಕ್ಕಂತಹ ಮಂತ್ರ. ಸೂರ್ಯನಲ್ಲಿರುವ\nಸೌರಶಕ್ತಿಯನ್ನು ನಮಗೆ ಹರಿಸುತ್ತ, ಸೌರಮಂಡಲದಲ್ಲಿರುವ ನಮ್ಮ ಜೀವಪ್ರಧಾನವಾದ ಭಗವಂತನ ಸ್ತೋತ್ರ\nಮಾಡುವುದು ಗಾಯತ್ರಿ. \"ಇಡೀ ಬ್ರಹ್ಮಾಂಡದ ನಿಯಾಮಕನಾಗಿದ್ದು, ಸೌರ ಶಕ್ತಿಯಿಂದ ಬಂದು, ನಮ್ಮ ಆತ್ಮದ\nಒಳಗೆ ನಮ್ಮ ಹೃದಯ ಕಮಲದಲ್ಲಿ \"ಧೀ' ಶಕ್ತಿಯನ್ನು ಪ್ರೇರಣೆ ಮಾಡುವಂತಹ ಶಕ್ತಿ ಭಗವಂತ' ಎನ್ನುವ ಸಮಷ್ಟಿ\nಚಿಂತನ ಇರುವ ಮಂತ್ರ ಗಾಯತ್ರಿ. ಗಾಯತ್ರಿ ವಿಶಿಷ್ಟವಾಗಿ(distinctly) ವೈದಿಕ ಛಂದಸ್ಸಾಗಿ ಬಳಕೆಯಾಗಿದೆ.\nಲೌಕಿಕವಾಗಿ ಇದರ ಬಳಕೆ ಇಲ್ಲ. ಗಾಯತ್ರಿಗೆ ಈ ವಿಶಿಷ್ಟ ಸ್ಥಾನ ಭಗವಂತನ ವಿಶೇಷ ವಿಭೂತಿಯಿಂದ ಬಂತು.\n[ಇಲ್ಲಿ ಒಂದು ವಿಷಯವನ್ನು ನಾವು ತಿಳಿದಿರಬೇಕು: ಐತರೇಯ ಉಪನಿಷತ್ತಿನಲ್ಲಿ ಬೃಹತೀ ಛಂದಸ್ಸನ್ನು ಶ್ರೇಷ್ಠ\nಎಂದು ಹೇಳಿದ್ದಾರೆ. ಇದಕ್ಕೆ ಕಾರಣ ಏನೆಂದರೆ ಅಭಿಮಾನಿ ದೇವತಾ ತಾರತಮ್ಯದಲ್ಲಿ ನೋಡಿದಾಗ ಗಾಯತ್ರಿ\nಅಭಿಮಾನಿ ದೇವತೆಯರು ಲಕ್ಷ್ಮಿ, ಸರಸ್ವತಿ, ಭಾರತಿ, ಗರುಡ ಮತ್ತು ಅಗ್ನಿಪತ್ನಿ ಸ್ವಾಹ. ಬೃಹತೀ ಛಂದಸ್ಸನ್ನು\nನೋಡಿದಾಗ ಅಲ್ಲಿ ಲಕ್ಷ್ಮಿ, ಸರಸ್ವತಿ, ಭಾರತಿ, ಗರುಡ ಮತ್ತು ಬೃಹಸ್ವತಿಪತ್ನಿ ತಾರ ಅಭಿಮಾನಿ ದೇವತೆಗಳು.\nಅಗ್ನಿಪತ್ನಿ ಸ್ವಾಹಕ್ಕಿಂತ ತಾರ ದೇವತಾ ತಾರತಮ್ಯದಲ್ಲಿ ಎತ್ತರದಲ್ಲಿರುವುದರಿಂದ, ದೇವತಾ ತಾರತಮ್ಯವನ್ನು\nಮುಖ್ಯವಾಗಿಟ್ಟು ಕೊಂಡು ಅಲ್ಲಿ ಹಾಗೆ ಹೇಳಿದ್ದಾರೆ. ಈ ವಿಚಾರ ತಿಳಿದಾಗ ಇಲ್ಲಿ ಗೊಂದಲವಿಲ್ಲ.]\n\n“ನಾನು ಮಾಸಗಳಲ್ಲಿ ಮಾರ್ಗಶಿರ, ಋತುಗಳಲ್ಲಿ ವಸಂತ” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಮಾರ್ಗಶಿರಮಾಸ-ಮಾಸಗಳಲ್ಲಿ\nಮೊದಲನೇ ಮಾಸ; ಕಾರ್ತಿಕ ಕೊನೆಯ ಮಾಸ. ಈ ಕಾರಣಕ್ಕಾಗಿ ಕಾರ್ತಿಕ ಮಾಸದಲ್ಲಿ (ಮಾರ್ಗಶಿರ ಮಾಸದ\nಮೊದಲು) ದೀಪಾವಳಿಯನ್ನು ಆಚರಿಸುತ್ತಾರೆ. ಒಂದು ವರ್ಷವನ್ನು ಕೃತಜ್ಞತೆಯಿಂದ ಕಳುಹಿಸಿಕೊಡುವುದು\nದೀಪಾವಳಿಯ ಮಹತ್ವ. ಮಾರ್ಗಶಿರಕ್ಕೆ ಆಗ್ರ-ಹಾಯಣ ಎನ್ನುತ್ತಾರೆ. ಹಾಯಣ ಎಂದರೆ ಮಾಸ. ಆಗ್ರ ಅಂದರೆ\nಮೊದಲನೆಯದು. ನಾವು ಗೀತಾಜಯಂತಿಯನ್ನು ಈ ಮಾಸದಲ್ಲಿ ಆಚರಿಸುತ್ತೇವೆ. ಇದರಿಂದ ಕೃಷ್ಣ ಅರ್ಜುನನಿಗೆ\nಗೀತೋಪದೇಶ ಮಾಡಿದ ಮಾಸ ಕೂಡಾ ಮಾರ್ಗಶಿರ ಎನ್ನಬಹುದು(ಈ ಬಗ್ಗೆ ಇನ್ನೂ ಹೆಚ್ಚಿನ ಸಂಶೋಧನೆ\nಅಗತ್ಯ). ಈ ಮಾಸದಲ್ಲಿ ವಿಭೂತಿಯಾಗಿ ಕುಳಿತಿರುವ ಭಗವಂತನ ವಿಭೂತಿನಾಮ 'ಮಾರ್ಗಶೀರ್ಷ'. ಸಾಧನಾ\nಮಾರ್ಗದಲ್ಲಿ ನಾವು ಸಾಗಬೇಕಾದ ಮಾರ್ಗದ ತುತ್ತತುದಿಯಾದ ಆ ಭಗವಂತ “ಮಾರ್ಗಶೀರ್ಷ'. ಹೂ ಅರಳಿ\nಗಿಡಮರಗಳು ಚಿಗುರುವ ವಸಂತ ಋತುವಿನಲ್ಲಿ 'ಕುಸುಮಾಕರನಾಗಿ' ನಾನಿದ್ದೇನೆ ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಕೆಟ್ಟವರಿಗೆ\nಕುಸ್ಸಿತವಾದ ಮತ್ತು ಸಜ್ಜನರಿಗೆ ಉತ್ತಮ ಜ್ಞಾನವನ್ನು ಕೊಡುವ ಭಗವಂತ “ಕುಸುಮಾಕರಃ'.",
  "10.36": "ದ್ಯೂತಮ್‌ ಛಲಯತಾಮ್‌ ಅಸ್ಮಿ ತೇಜಃ ತೇಜಸ್ವಿನಾಮ್‌ ಅಹಮ್‌ ।\n\nಜಯಃ ಅಸ್ಮಿ ವ್ಯವಸಾಯಃ ಅಸ್ಮಿ ಸತ್ತ್ವಮ್‌ ಸತ್ತ್ವವತಾಮ್‌ ಅಹಮ್‌-ಮೋಸಗಾರರ ಜೂಜು ನಾನು.\n[ಕ್ರೀಡಾರೂಪನಾಗಿ 'ದ್ಯೂತ' ಎನ್ನಿ ಸಿ ಜೂಜಿನಲ್ಲಿದ್ದೇನೆ.] ವೀರರಾದವರ ಬೀರ ನಾನು. [ಪ್ರಕಾಶರೂಪನಾದ್ದರಿಂದ\n“ತೇಜಸ್‌' ಎನ್ನಿ ಪಿ ಬೀರದಲ್ಲಿದ್ದೇನೆ.] ಗೆಲುವು ನಾನು. [ಎಲ್ಲವನ್ನು ಗೆದ್ದವನಾಗಿ “ಜಯ' ಎನ್ನಿ ಸಿ ಗೆಲುವಿನಲ್ಲಿದ್ದೇನೆ.]\nದುಡಿಮೆ ನಾನು. [ನಿಶ್ಚಯ ಜ್ಞಾನರೂಪನಾದ್ದರಿಂದ 'ವ್ಯವಸಾಯ' ಎನ್ನಿಸಿ ದುಡಿಮೆಯಲ್ಲಿದ್ದೇನೆ.] ಹಿರಿಯ ವ್ಯಕ್ತಿಗಳ\nಘನತೆ ನಾನು.[ಸದ್ಗುಣಗಳ ಗಣಿಯಾಗಿ “ಸತ್ವ' ಎನ್ನಿಸಿ ದೊಡ್ಡವರ ಘನತೆಯಲ್ಲಿದ್ದೇನೆ.]\n\nಕೌರವ ಪಾಂಡವರ ನಡುವೆ ಯುದ್ಧವಾಗಲು ಕಾರಣವಾಗಿ ಕಾಣುವುದು ದ್ಯೂತ. ಇದು ಮೋಸಗಾರಿಕೆಯಲ್ಲಿ\nಅತ್ಯಂತ ಶ್ರೇಷ್ಠ ಕಲೆ! ಭಗವಂತ 'ದ್ಯೂತ' ಎನ್ನಿಸಿ ಜೂಜಿನಲ್ಲಿದ್ದಾನೆ. ಇಲ್ಲಿ ಭಗವಂತನ ನಾಮ 'ದ್ಯೂತ'. ದಿವು\nಅಂದರೆ ಕ್ರೀಡೆ. ಸದಾ ಸೃಷ್ಟಿ ಸ್ಥಿತಿ ಸಂಹಾರಗಳ ಕ್ರೀಡೆಯಲ್ಲಿ ನಿರತನಾದ ಭಗವಂತ \"ದ್ಯೂತ' ಶಬ್ದ ವಾಚ್ಯ.\nಆತ್ಮಬಲವುಳ್ಳವರ ತೇಜಸ್ಸು ಭಗವಂತ. ಜಯಃ ನಾಮಕನಾಗಿ ಗೆಲುವಿನಲ್ಲಿ ಭಗವಂತನಿದ್ದಾನೆ. ಜಗತ್ತಿನ ಎಲ್ಲಾ\nವಿಜಯಗಳ ಪ್ರೇರಕ ಭಗವಂತ. ಒಂದು ಕಾರ್ಯದಲ್ಲಿ ಉತ್ಸಾಹದಿಂದ ತೊಡಗುವಂತೆ ಮಾಡುವವನು\n\"ವ್ಯವಸಾಯ' ನಾಮಕ ಭಗವಂತ. ಬಲನಿಯಾಮಕನಾಗಿ ಆತ ಬಲಶಾಲಿಗಳಲ್ಲಿ “ಸತ್ವ' ನಾಮಕನಾಗಿ\nಕೂತಿದ್ದಾನೆ.",
  "10.37": "ವೃಷ್ಟೀನಾಮ್‌ ವಾಸುದೇವಃ ಅಸ್ಮಿ ಪಾಂಡವಾನಾಮ್‌ ಧನಂಜಯಃ ।\n\nಮುನೀನಾಮ್‌ ಅಪಿ ಅಹಮ್‌ ವ್ಯಾಸಃ ಕವೀನಾಮ್‌ ಉಶನಾ ಕವಿಃ - ವೃಷ್ಟಿವಂಶದ ರಾಜನ್ಯರಲ್ಲಿ\n[ವಾಸು-ಎಲ್ಲವನ್ನೂ ಆವರಿಸಿ, ಎಲ್ಲದರೊಳಗೂ ನೆಲೆಸಿರುವ, ದೇವ-ದಿವ್ಯರೂಪನಾದ್ದರಿಂದ] ವಾಸುದೇವನಾಗಿ\nಅವತರಿಸಿದ್ದೇನೆ. ಪಾಂಡವರಲ್ಲಿ ಅರ್ಜುನ ನಾನು. (ಸಿರಿಯನ್ನು ಗೆದ್ದವನಾಗಿ “ಧನಂಜಯ' ಎನ್ನಿಸಿ\nಅರ್ಜುನನಲ್ಲಿದ್ದೇನೆ.] ಮುನಿಗಳಲ್ಲಿ ([ವಿ:ಎಲ್ಲಕ್ಕಿಂತ ವಿಶಿಷ್ಟನಾಗಿ, ಆ-ಎಲ್ಲೆಡೆಯೂ, ಸಃ ಇಅವನೇ\nತುಂಬಿರುವುದರಿಂದ] ವ್ಯಾಸ ನಾನು. ವಿಜ್ಞಾನಿಗಳಲ್ಲಿ ಹಿರಿಯ ವಿದ್ವಾಂಸನಾದ ಶುಕ್ರ ನಾನು.\n[ಇಚ್ಛಾರೂಪನಾದ್ದರಿಂದ \"ಉಶನಸ್‌' ಎನ್ನಿಸಿ ದೈತ್ಯಗುರು ಶುಕ್ರನಲ್ಲಿದ್ದೇನೆ.]\n\nಸಾಕ್ಷಾತ್‌ ವಿಭೂತಿಯನ್ನು ಹೇಳುತ್ತಾ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ವೃಷ್ಟೀನಾಮ್‌ ವಾಸುದೇವಃ ಅಸ್ಮಿ” ಎಂದು. ಇಲ್ಲಿ\nಭಗವಂತನ ವಿಭೂತಿ ನಾಮ “ವಾಸುದೇವಃ. ಎಲ್ಲೆಡೆ ಇದ್ದರೂ ಕಾಣಿಸದೆ, ಅಪರೋಕ್ಷ ಜ್ಞಾನವನ್ನು ಕರುಣಿಸಿ\nಪ್ರತ್ಯಕ್ಷನಾಗುವ ಭಗವಂತ ವಾಸುದೇವಃ. ಪಾಂಡವರಲ್ಲಿ 'ಧನಂಜಯಃ' ನಾನು ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಇದು\nಏಕದೇಶ ವಿಭೂತಿ. ಅರ್ಜುನನಲ್ಲಿ ಭಗವಂತನ ವಿಶೇಷ ಆವೇಶ ಇತ್ತು. ಆತನಲ್ಲಿ ಭಗವಂತ “ಧನಂಜಯಃ\nನಾಮಕನಾಗಿ ನಿಂತಿದ್ದ. ಧನಂಜಯಃ ಎನ್ನುವಲ್ಲಿ ಧನ ಎಂದರೆ ಜ್ಞಾನ. ಭಗವಂತನ ಅರಿವು, ಅದರಿಂದ\n\nಪಡೆಯುವ ಮೋಕ್ಷ ಶಾಶ್ವತ ಧನ. ಅದನ್ನು ಕೊಡುವ ಭಗವಂತ ಧನಂಜಯಃ. ಮುನಿಗಳಲ್ಲಿ ವ್ಯಾಸ. ಇದು\nಭಗವಂತನ ಸಾಕ್ಷಾತ್‌ ವಿಭೂತಿ. ವ್ಯಾಸರು ವೇದವನ್ನು 1137 ಸಂಹಿತೆಯಾಗಿ ವಿಭಾಗಮಾಡಿ ಜ್ಞಾನಿಗಳ\nಮುಖೇನ ನಮಗೆ ಕೊಟ್ಟಿದ್ದಾರೆ. ಪ್ರಧಾನವಾಗಿ ವೇದಗಳು ನಾಲ್ಕು. ಪದ್ಯ ಸಂಕಲನ ಋಗ್ವೇದ, ಗದ್ಯ ಸಂಕಲನ\nಯಜುರ್ವೇದ, ಗಾನಕ್ಕೋಸ್ಕರ ಸಾಮವೇದ, ಅಥರ್ವ ಮುನಿ ಬ್ರಹ್ಮನಿಂದ ಉಪದೇಶ ಪಡೆದು ಬರೆದ ಅಥರ್ವಣ\nವೇದ. ಮೂಲಭೂತವಾಗಿ ವೇದಗಳು ಮೂರು ಆದರೆ ಋಷಿ ಸಂಪ್ರದಾಯದಿಂದ ನಾಲ್ಕು ವೇದಗಳ\nಸೃಷ್ಟಿಯಾಯಿತು. ಇದನ್ನೇ ವೇದವ್ಯಾಸರು ನಾಲ್ಕು ಜನ ಮುನಿಗಳಿಗೆ (ಬೈಲ, ವೈಶಂಪಾಯನ, ಸುಮಂತು\nಮತ್ತು ಜೈಮಿನಿಗೆ) ಹೇಳಿದರು. ಈ ನಾಲ್ಕು ಮುನಿಗಳು ಮತ್ತೆ ವೇದವನ್ನು ಅನೇಕ ಶಾಖೆಗಳಾಗೀಿ(ಸಂಹಿತೆ)\nವಿಂಗಡಿಸಿದರು. ಋಗ್ವೇದದಲ್ಲಿ 24 ಸಂಹಿತೆಗಳಿವೆ; ಯಜುರ್ವೇದದಲ್ಲಿ ಪ್ರಮುಖವಾಗಿ ಎರಡು ಶಾಖೆ. ಒಂದು ಶುಕ್ಲ\nಯಜುರ್ವೇದ ಹಾಗೂ ಇನ್ನೊಂದು ಕೃಷ್ಣ ಯಜುರ್ವೇದ. ಶುಕ್ಲ ಯಜುರ್ವೇದದಲ್ಲಿ 15 ಸಂಹಿತೆ, ಹಾಗೂ ಕೃಷ್ಣ\nಯಜುರ್ವೇದದಲ್ಲಿ 86 ಸಂಹಿತೆ, ಒಟ್ಟು 101 ಸಂಹಿತೆ. ಸಾಮವೇದದಲ್ಲಿ 1000 ಶಾಖೆಗಳು, ಒಂದು ಸಾವಿರ\nಬಗೆಯ ಗಾನ ಪದ್ಧತಿ! ಆದರೆ ಇಂದು ಕೇವಲ ಮೂರು (ಜೈಮಿನಿಯ, ರಣಾಯನಿಯ ಹಾಗೂ ಕೌತುಮನ)\nಗಾನಪದ್ಧತಿ ಮಾತ್ರ ಪ್ರಚಲಿತದಲ್ಲಿದೆ. ಅಥರ್ವ ವೇದದಲ್ಲಿ ಒಟ್ಟು 12 ಶಾಖೆಗಳು. ಹೀಗೆ ವೇದವನ್ನು 1137\n(24+101+12+1000) ಸಂಹಿತೆಗಳಾಗಿ ವಿಂಗಡಿಸಿ ವಿಸ್ತಾರ ಮಾಡಿದ ಮುನಿ ವ್ಯಾಸ. ಮನುಷ್ಯ ಸ್ವಭಾವದ ಬುದ್ಧಿ\nವೈಚಿತ್ರ್ಯದ ಜ್ಞಾನ ಸಾಗರವನ್ನು ನಮ್ಮ ಮುಂದೆ ತೆರೆದಿಟ್ಟ, ಎಲ್ಲೆಡೆ ತುಂಬಿರುವ ಭಗವಂತ ವ್ಯಾಸಃ. ದೈತ್ಯ ಗುರು\nಶುಕ್ರಾಚಾರ್ಯರಲ್ಲಿ \"ಉಶನ' ನಾಮಕನಾಗಿ ಭಗವಂತ ನಿಂತ. ಈ ಕಾರಣದಿಂದ ಗ್ರಹಗಳಲ್ಲಿ ಶುಕ್ರ ಒಬ್ಬನಾಗಿ\nಸ್ಥಾನ ಪಡೆದ. ತನ್ನ ಇಚ್ಛಾಮಾತ್ರದಿಂದಲೇ ಎಲ್ಲಾ ಕಾರ್ಯವನ್ನು ಮಾಡುವ ಭಗವಂತ \"ಉಶನ'\n",
  "10.38": "ದಂಡಃ ದಮಯತಾಮ್‌ ಅಸ್ಮಿ ನೀತಿಃ ಅಸ್ಮಿ ಜಿಗೀಷತಾಮ್‌ ।\n\nಮೌನಮ್‌ ಚ ಏವ ಅಸ್ಮಿ ಗುಹ್ಯಾನಾಮ್‌ ಜ್ಞಾನಮ್‌ ಜ್ಞಾನವತಾಮ್‌ ಅಹಮ್‌ -ಬಗ್ಗುಬಡಿಯುವವರ ದಂಡನೀತಿ\nನಾನು. [ದಂಡಿಸುವವನಾದ್ದರಿಂದ “ದಂಡ' ಎನ್ನಿಸಿ ದಂಡನೀತಿಯಲ್ಲಿದ್ದೇನೆ.] ಗೆಲ್ಲಲಯಸುವವರ ನಯಗಾರಿಕೆ\nನಾನು. [ಗೆಲುವಿನತ್ತ ಕರೆದೊಯ್ಯುವುದರಿಂದ 'ನೀತಿ' ಎನ್ನಿಸಿ ನಯಗಾರಿಕೆಯಲ್ಲಿದ್ದೇನೆ.] ಗುಟ್ಟುಗಳಲ್ಲಿ ಮೌನ\nನಾನು. [ಮುನಿಗಳಿಂದ ಸ್ತುತನಾಗಿ 'ಮೌನ' ಎನ್ನಿಸಿ ಮೌನದಲ್ಲಿದ್ದೇನೆ.] ಬಲ್ಲವರ ತಿಳಿವು ನಾನು. [ಅರಿವಿನ\nಮೂರ್ತಿಯಾದ್ದರಿಂದ “ಜ್ಞಾನ” ಎನ್ನಿಸಿ ತಿಳಿವಿನಲ್ಲಿದ್ದೇನೆ.]\n\n“ದುಷ್ಟರನ್ನು ದಮನ ಮಾಡುವ ದಮನಶಕ್ತಿ ನಾನು” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಈ ದಮನಶಕ್ತಿಯಾಗಿ ವೀರರಲ್ಲಿ\nಭಗವಂತ ಕೂತಿದ್ದಾನೆ. ದಂಡ ಎಂದರೆ ಶಿಕ್ಷೆ. ಸಂಸ್ಕೃತದಲ್ಲಿ ಶಿಕ್ಷೆ ಎನ್ನುವುದಕ್ಕೆ ಶಿಕ್ಷಣ ಎನ್ನುವ ಅರ್ಥವಿದೆ. ಆದರೆ\nಇಲ್ಲಿ ದಂಡ ಎಂದರೆ ದಂಡಿಸುವುದು(Punishment). ತಪ್ಪು ಮಾಡಿದವರಿಗೆ ದೇವರ ರಾಜ್ಯದಲ್ಲಿ ಕ್ಷಮೆ ಇಲ್ಲ. ನಾವು\nಮಾಡಿದ ಕರ್ಮವನ್ನು ನಾವು ಅನುಭವಿಸಲೇಬೇಕು. ತಪ್ಪು ಮಾಡಿದವರಿಗೆ ನಿರ್ದಾಕ್ಷಿಣ್ಯ ಹಾಗೂ ನಿಷ್ಠುರವಾದ\n\nದಂಡನೆಯನ್ನು ಕೊಡುವ ಭಗವಂತ \"ದಂಡಃ'. ಗೆಲ್ಲುವ ಶಕ್ತಿಯಾಗಿ ಎಲ್ಲರನ್ನು ನಿಯಂತ್ರಣ ಮಾಡುವ ಭಗವಂತ\n\"ನೀತಿ, ಮನನಶಕ್ತಿಯಾಗಿ ನಿಂತ ಭಗವಂತ \"ಮೌನಃ'. ಬಲ್ಲವರ ತಿಳಿವಾಗಿರುವ ಭಗವಂತ “ಜ್ಞಾನಃ.\n\nಮೂಲಭೂತವಾಗಿ ವಿಭೂತಿಗಳ ವಿಸ್ತಾರ ಇಲ್ಲಿಗೆ ಮುಗಿಯಿತು. ಮುಂದೆ ವಿಭೂತಿಯ ಉಪಸಂಹಾರವನ್ನು ಈ\nಅಧ್ಯಾಯದ ಉಳಿದ ಭಾಗದಲ್ಲಿ ನೋಡೋಣ.\n",
  "10.39": "ಯತ್‌ ಚ ಅಪಿ ಸರ್ವ ಭೂತಾನಾಮ್‌ ಬೀಜಮ್‌ ತತ್‌ ಅಹಮ್‌ ಅರ್ಜುನ |\n\nನ ತತ್‌ ಅಸ್ತಿ ವಿನಾ ಯತ್‌ ಸ್ಯಾತ್‌ ಮಯಾ ಭೂತಮ್‌ ಚರ ಅಚರಮ್‌ -ಅರ್ಜುನಾ, ಸಮಸ್ತ ಜೀವಿಗಳಲ್ಲಿ\nಏನೆಲ್ಲಾ ವಿಶಿಷ್ಟ ಗುಣವಿದೆಯೋ ಅವುಗಳಲ್ಲಿ ನಾನೇ ಇದ್ದು ಆ ಶಕ್ತಿ ನೀಡಿದ್ದೇನೆ. ನನ್ನನ್ನು ಹೊರತುಪಡಿಸಿ ಈ\nಚರಾಚರದಲ್ಲಿ ಯಾವುದೂ ತಾನೇ ತಾನಾಗಿ ಇಲ್ಲ.\n\n“ಈ ಜಗತ್ತಿನಲ್ಲಿರುವ ಸಮಸ್ತ ವಸ್ತು(ಜಡ-ಚೇತನ)ವಿಗೂ ಮೂಲಭೂತವಾಗಿರುವ ಅಭಿವ್ಯಂಜಕ ರೂಪ ಮತ್ತು ಶಕ್ತಿ\nಕೊಡುವವನು ನಾನು” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಹೀಗೆ ಭಗವಂತ ಸಮಸ್ತ ಸೃಷ್ಟಿಗೂ ಬೀಜಪುರುಷನಾಗಿ ನಿಂತಿದ್ದಾನೆ.\nಕಣ್ಣಿಗೆ ಕಾಣದ ಜೀವಕ್ಕೆ ಕಣ್ಣಿಗೆ ಕಾಣುವ ಶರೀರ ಕೊಡುವವನು ಆತ. ಗಂಡಿನ ರೇತಸ್ಸಿನಲ್ಲಿದ್ದು, ಜೀವವನ್ನು\nರೇತಸ್ಸಿನ ಮುಖೇನ ಹೆಣ್ಣಿನ ದೇಹದೊಳಗೆ ಸೇರಿಸಿ, ಅಲ್ಲಿ ಜೀವಕ್ಕೆ ಒಂದು ರೂಪವನ್ನು ಕೊಟ್ಟು ಬೆಳಗಿಸುವವ\nಭಗವಂತ. ಹೀಗೆ ಈ ಪ್ರಪಂಚದಲ್ಲಿರುವ ಚೇತನಾಚೇತನ ಅಥವಾ ಚರಾಚರಾತ್ಮಕ-ಎಲ್ಲವನ್ನೂ ಹುಟ್ಟಿಸುವವನು\nಭಗವಂತ. “ಈ ಪ್ರಪಂಚದಲ್ಲಿ ನನ್ನನ್ನು ತೊರೆದು ಸ್ವತಂತ್ರವಾಗಿ ಯಾವ ವಸ್ತುವೂ ಇಲ್ಲ” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಇದು\nವೈದಿಕ ಪರಂಪರೆಯಲ್ಲಿ ಇರುವ ಗೊಂದಲಕ್ಕೆ ಕೃಷ್ಣ ಕೊಟ್ಟ ನೇರ ಉತ್ತರ. ಜೀವ ಮತ್ತು ಭಗವಂತ ಒಂದೇ ಅಲ್ಲ.\nಜೀವ ಭಗವಂತನ ಪ್ರತಿಬಿಂಬ. ಎಲ್ಲವೂ ಇದೆ. ಆದರೆ ಭಗವಂತನನ್ನು ಬಿಟ್ಟು ಸ್ವತಂತ್ರ ಅಸ್ತಿತ್ವ ಯಾರಿಗೂ ಇಲ್ಲ.\n",
  "10.40": "ನ ಅಂತಃ ಅಸ್ತಿ ಮಮ ದಿವ್ಯಾನಾಮ್‌ ವಿಭೂತೀನಾಮ್‌ ಪರಂತಪ ।\nಏಷಃ ತು ಉದ್ದೇಶತಃ ಪ್ರೋಕ್ತಃ ವಿಭೂತೇಃ ವಿಸ್ತರಃ | ಮಯಾ-ಓ ಪರಂತಪಾ, ನನ್ನ ದಿವ್ಯರೂಪಗಳ\nಹಿರಿಮೆಗಳಿಗೆ ಕೊನೆಯಿಲ್ಲ. ನನ್ನ ಹಿರಿಮೆಯ ಬಿತ್ತರದ ಕೆಲವನ್ನ ಷ್ಟೇ ಇಲ್ಲಿ ಹೆಸರಿಸಿ ಹೇಳಿದೆ.\n\nಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ನನ್ನ ವಿಭೂತಿ ಪ್ರಪಂಚದಲ್ಲಿರುವ ಪ್ರತಿಯೊಂದು ವಸ್ತುವಿನಲ್ಲೂ ಇದೆ. ಅದನ್ನು ಹೇಳಿ ಕೊನೆ\nಇಲ್ಲ” ಎಂದು. ಲೋಕವಿಲಕ್ಷಣವಾದ ಭಗವಂತನ ವಿಭೂತಿಗೆ ಕೊನೆ ಇಲ್ಲ. ಅದನ್ನು ಹೇಳಿ ಮುಗಿಯುವುದಿಲ್ಲ. ಇಲ್ಲಿ\nಕೃಷ್ಣ ಅತ್ಯಂತ ಮುಖ್ಯವಾದ, ನಾವು... ನಿರಂತರ ಉಪಾಸನೆ. ಮಾಡಬೇಕಾದ, ನಿತ್ಯ\nಅನುಸಂಧಾನದಲ್ಲಿರಬೇಕಾದುದ್ದನ್ನು ಹೇಳಿದ್ದಾನೆ ಅಷ್ಟೆ\n",
  "10.41": "ಯತ್‌ ಯತ್‌ ವಿಭೂತಿ ಮತ್‌ ಸತ್ತ್ವಮ್‌ ಶ್ರೀಮತ್‌ ಊರ್ಜಿತಮ್‌ ಏವ ವಾ |\n\nತತ್‌ ತತ್‌ ಏವ ಅವಗಚ್ಛ ತ್ವಮ್‌ ಮಮ ತೇಜಃ ಅಂಶ ಸಂಭವಮ್‌-ಗುಂಪಿನಲ್ಲಿ ಮಿಗಿಲಾದದ್ದು , ಸಿರಿಯಲ್ಲಿ\nಹಿರಿದಾದದ್ದು. ಎತ್ತರದಲ್ಲಿ ಮೆರೆದದ್ದು ಯಾವುದೆಲ್ಲಾ ಇದೆಯೋ ಅದೆಲ್ಲವೂ ನನ್ನ ಹಿರಿಮೆಯ ಬೆಳಕಿನ ಕಿಡಿಯಿಂದ\nಮೂಡಿಬಂದದ್ದು ಎಂದು ತಿಳಿ.\n\nಒಟ್ಟಿನಲ್ಲಿ ಒಬ್ಬ ವ್ಯಕ್ತಿಯಲ್ಲಿ, ಒಂದು ವಸ್ತುವಿನಲ್ಲಿ, ಇನ್ನೊ ಬ್ಬರಲ್ಲಿಲ್ಲಲ ಯಾವ ವಿಶಿಷ್ಟ ಗುಣವಿದೆಯೋ ಅದು\nಭಗವಂತನ ಹಿರಿಮೆಯ ಒಂದು ಬೆಳಕಿನ ಕಿಡಿ. ಇದು ಭಗವಂತನ ಅನಂತ ತೇಜಸ್ಸಿ ನ ಒಂದು ತುಣುಕು.",
  "10.42": "ಅಥವಾ ಬಹುನಾ ಏತೇನ ಕಿಮ್‌ ಜ್ಞಾತೇನ ತವ ಅರ್ಜುನ ।\n\nವಿಷಭ್ಯ ಅಹಮ್‌ ಇದಮ್‌ ಕೃತ್ಸ್ನಮ್‌ ಏಕ ಅಂಶೇನ ಸ್ಥಿತಃ ಜಗತ್‌ -ಅಥವಾ, ಓ ಅರ್ಜುನಾ, ಎಲ್ಲವನ್ನು ತಿಳಿದು\nಏನು ಬಂತು ? ಸಾರವಿದು: ನಾನು ನನ್ನ ಒಂದೇ ಅಂಶದಿಂದ ಈ ಇಡಿಯ ವಿಶ್ವವನ್ನು ತಬ್ಬಿ ತಡೆಹಿಡಿದು\nನಡೆಸುತ್ತಿದ್ದೇನೆ.\n\nಒಂದೊಂದನ್ನು ಪ್ರತ್ಯೇಕ ತಿಳಿದು ಹೇಳುವುದು ಅಸಾಧ್ಯ. ಈ ರೀತಿ ಮಾಡುವ ಅಗತ್ಯವೂ ಇಲ್ಲ.\nಎಲ್ಲವುದರೊಳಗೂ ಒಂದು ವಿಶಿಷ್ಟ ಶಕ್ತಿಯಾಗಿ ಭಗವಂತನಿದ್ದಾನೆ. ಎಲ್ಲದರಲ್ಲೂ ಭಗವಂತನ ವಿಭೂತಿ ಅಡಗಿದೆ.\nಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ ಇಡೀ ವಿಶ್ವವನ್ನು ನಾನು ನನ್ನ ಸಾಮರ್ಥ್ಯದ ಒಂದು ತುಣುಕಿನಿಂದ ವ್ಯಾಪಿಸಿ ನಿಂತಿದ್ದೇನೆ”\nಎಂದು. ಪುರುಷ ಸೂಕ್ತದಲ್ಲಿ ಹೇಳುವಂತೆ:\n\nಪಾದೋಸ್ಯ ವಿಶ್ವಾ ಭೂತಾನಿ| ತ್ರಿಪಾದಸ್ಯಾಮೃತಂ ದಿವಿ|\n\nತ್ರಿಪಾದೂರ್ಧ್ವ ಉದೈತ್ಪುರುಷಃ। ಪಾದೋಸ್ಯೇಹಾಭವಾತ್ಹು ನಃ।\n\nತತೋ ವಿಷ್ಟಂವ್ಯಕ್ರಾಮತ್‌।| ಸಾಶನಾನಶನೇ ಅಭಿ|\n\nಈ ಪ್ರಪಂಚದಲ್ಲಿ ವ್ಯಾಪಿಸಿರುವುದು ಭಗವಂತನ ಕೇವಲ ಕಾಲು ಭಾಗವಷ್ಟೆ. ಅಮೃತಮಯವಾದ ಮುಕ್ಕಾಲು\nಭಾಗ ದಿವ್ಯಲೋಕ (ಮುಕ್ತಲೋಕ) ದಲ್ಲಿ ನೆಲೆಸಿದೆ. “ಜಗತ್ತಿನ ಸಮಸ್ತ ವಸ್ತುವಿನ ಒಳಗೂ ಹೊರಗೂ ತುಂಬಿ\n\nನಾನು ವಿಶ್ವ ರೂಪನಾಗಿದ್ದೇನೆ” ಎಂದು ಕೃಷ್ಣ ಹೇಳಿದ ಎನ್ನುವಲ್ಲಿಗೆ ಭಗವಂತನ ವಿಭೂತಿ ಎನ್ನುವ ಈ ಅಧ್ಯಾಯ\nಮುಗಿಯಿತು.\n\nಇತಿ ದಶಮೋ*ಧ್ಯಾಯಃ\nಹತ್ತನೆಯ ಅಧ್ಯಾಯ ಮುಗಿಯಿತು\n\nಅಧ್ಯಾಯ ಹನ್ನೊಂದು\n\nಈ ಅಧ್ಯಾಯ ಭಗವಂತನ ಉಪಾಸನೆ ಮಾಡುವಾಗ ಆತನನ್ನು ಹೇಗೆ ಚಿಂತನೆ ಮಾಡಬೇಕು ಎಂದು ಹೇಳುವ\nಅಧ್ಯಾಯ. ಇದು ಭಗವಂತನ ವಿಶ್ವರೂಪ ದರ್ಶನ ಅಧ್ಯಾಯ. ಕೃಷ್ಣ ಅರ್ಜುನನಿಗೆ ದಿವ್ಯನೇತ್ರವನ್ನು ಕರುಣಿಸಿ\nತನ್ನ ವಿಶ್ವರೂಪ ದರ್ಶನ ಮಾಡಿಸುತ್ತಾನೆ. ಆ ವಿಶ್ವರೂಪದ ವರ್ಣನೆ ಇಲ್ಲಿದೆ. ಇಲ್ಲಿ ಸರ್ವವ್ಯಾಪ್ತ,\nಸರ್ವಾಂತರ್ಯಾಮಿ, ಸರ್ವಸಮರ್ಥ ಭಗವಂತನ ಚಿಂತನೆ ಹೇಗೆ ಮಾಡಬೇಕು ಎನ್ನುವ ಮಾರ್ಗದರ್ಶನವಿದೆ.\nಭಗವಂತನ ರೂಪವನ್ನು ಯಾವುದೋ ಒಂದು ಲೌಕಿಕ ಅನುಭವದೊಂದಿಗೆ ಸಮೀಕರಿಸಲು ಸಾಧ್ಯವಿಲ್ಲ. ಅದು\nಲೋಕಾತೀತ ಅನುಭವ. ಆ ಅದ್ಭು ತ ಅನುಭವದ ಚಿತ್ರಣ ಈ ಅಧ್ಯಾಯ.\n\nಭಗವಂತನ ಸರ್ವಗತವಾದ ವಿಶ್ವರೂಪವನ್ನು ಎಲ್ಲರೂ ಧ್ಯಾನ ಮಾಡಲು ಸಾಧ್ಯವಿಲ್ಲ. ಆದರೆ ಎಲ್ಲಾ ಕಡೆ\nತುಂಬಿರುವ ಭಗವಂತನ ಕಿಂಚಿತ್‌ ದರ್ಶನ ಪ್ರತಿಯೊಬ್ಬರೂ ಧ್ಯಾನ ಯೋಗದಲ್ಲಿ ಪಡೆಯಲು ಸಾಧ್ಯವಿದೆ. ಹೇಗೆ\nಅರ್ಜುನನಿಗೆ ಕೃಷ್ಣ ತನ್ನ ವಿಶ್ವರೂಪವನ್ನು ತೋರಿಸಿದನೋ ಹಾಗೆ ನಮಗೆ ಧ್ಯಾನದಲ್ಲಿ ಕೂಡಾ ತನ್ನ ರೂಪವನ್ನು\nಆತನೇ ತೋರಿಸಬೇಕು. ಇದು ಹೊರಪ್ರಪಂಚದಲ್ಲಿ ಕಾಣುವ ರೂಪವಲ್ಲ. ನಾವು ನಮ್ಮ ಒಳಗಣ್ಣನ್ನು ತೆರೆದು\nಕುಳಿತು ಧ್ಯಾನ ಮಾಡಬೇಕು, ಭಗವಂತನಲ್ಲಿ ಶರಣಾಗಬೇಕು. ಕಾತರತೆಯಿಂದ ಕರೆದಾಗ ಒಳಗಿನಿಂದ ಏನು\nಅನುಭೂತಿ ಬರುತ್ತದೋ ಅದು ಲೌಕಿಕ ಅನುಭೂತಿಯನ್ನು ಮೀರಿದ ವಿಚಾರ.\n\nಈ ಅಧ್ಯಾಯದಲ್ಲಿ ಭಗವಂತನ ಮಾತು ಕಡಿಮೆ. ಇಲ್ಲಿ ಕೃಷ್ಣನ ವಿಶ್ವರೂಪವನ್ನು ಕಂಡವರ ಮಾತಿದೆ. ಅವರು\nಕಂಡ ರೀತಿಯನ್ನು ಕೇಳಿ ನಾವು ಭಗವಂತನನ್ನು ಕಾಣಲು ಪ್ರಯತ್ನ ಮಾಡಬೇಕು. ಇದು ನಮ್ಮ ಅಂತರಂಗದ\nಅಧ್ಯಾತ್ಮದ ಸಾಕ್ಷಾತ್ಕಾರಕ್ಕೆ ಪೂರಕವಾದ, ಧ್ಯಾನದ ದಾರಿಯಲ್ಲಿ ನಮ್ಮನ್ನು ಕೊಂಡೊಯ್ಯುವ ಬಹಳ ಮಹತ್ವದ\nಅಧ್ಯಾಯ. ಬನ್ನಿ, ವ್ಯಾಸರು ದಾಖಲಿಸಿದ ಭಗವಂತನ ಅಪೂರ್ವ ವಿಶ್ವರೂಪ ವರ್ಣನೆಯನ್ನು ಕೇಳಿ\nಧನ್ಯರಾಗೋಣ.\n\nಅಧ್ಯಾಯಕ್ಕೆ ಪ್ರವೇಶಿಸುವ ಮುನ್ನ ನಾವು ಒಂದು ವಿಚಾರವನ್ನು ತಿಳಿದುಕೊಳ್ಳಬೇಕು. ನಮ್ಮಲ್ಲಿ ಕೆಲವರಿಗೆ\nಒಂದು ತಪ್ಪು ತಿಳುವಳಿಕೆ ಇದೆ. “ಅರ್ಜುನನಿಗೆ ಭಗವಂತನ ಸಂದೇಶವನ್ನು ಮನವರಿಕೆ ಮಾಡಿಸಲು ಕೃಷ್ಣ ತನ್ನ\nವಿಶ್ವರೂಪ ದರ್ಶನ ಮಾಡಿಸಬೇಕಾಯಿತು” ಎಂದು. “ಸ್ವತಃ ಶ್ರೀಕೃಷ್ಣನಿಂದಲೇ ಉಪದೇಶ ಪಡೆದರೂ ಸಹ\nಅರ್ಜುನನಿಗೆ ಮನವರಿಕೆ ಆಗಲಿಲ್ಲ, ಇನ್ನು ನಮ್ಮ ಪಾಡೇನು? ನಮಗೆ ಯಾರು ವಿಶ್ವರೂಪ ದರ್ಶನ\nಮಾಡಿಸುತ್ತಾರೆ”-ಎಂಂದು ಯೋಚಿಸುವವರಿದ್ದಾರೆ. ಆದರೆ ಇದು ನಮ್ಮ ತಪ್ಪು ತಿಳುವಳಿಕೆ. ಅರ್ಜುನನಿಗೆ\nಭಗವಂತನ ಸಂದೇಶ ಪೂರ್ಣ ಮನವರಿಕೆ ಆಗಿತ್ತು. ಈ ವಿಚಾರ ಈ ಅಧ್ಯಾಯದ ಮೊದಲ ಶ್ಲೋಕದಲ್ಲೇ\nತಿಳಿಯುತ್ತದೆ. ಅರ್ಜುನ ಹೇಳುತ್ತಾನೆ “ಮೋಹೋಯಂ ವಿಗತೋ ಮಮ”- “ನಿನ್ನ ಮಹಿಮೆ ತಿಳಿದು ನನ್ನ ಎಲ್ಲಾ\nಸಂಶಯವೂ ಕಳೆಯಿತು' ಎಂದು. ಇದರಿಂದ ತಿಳಿಯುವುದೇನೆಂದರೆ ಅರ್ಜುನ ಭಗವಂತನ ವಿಶ್ವರೂಪ ದರ್ಶನ\nಬಯಸಿದ್ದು ಕೇವಲ ನೋಡಿ ಧನ್ಯನಾಗುವುದಕ್ಕೋಸ್ಕರವೇ ಹೊರತು, ಪುರಾವೆಗಾಗಿ ಅಲ್ಲ. ಸಾಮಾನ್ಯವಾಗಿ\nಮನುಷ್ಯ ಸ್ವಭಾವವೇನೆಂದರೆ ಒಂದು ವಿಷಯವನ್ನು ಕೇಳಿದ ಮೇಲೆ ಅದನ್ನೊಮ್ಮೆ ನೋಡಬೇಕು ಎನ್ನುವ ಸಹಜ\nಅಭಿಲಾಷೆ. ಅರ್ಜುನ ಕೃಷ್ಣನ ಮುಂದಿಟ್ಟಿರುವುದು ಕೂಡಾ ಇಂತಹದ್ದೇ ಬಯಕೆಯನ್ನು. ಮುಂದಿನ ನಾಲ್ಕು\nಶ್ಲೋಕಗಳಲ್ಲಿ ಈ ವಿಚಾರ ಸ್ಪಷ್ಟವಾಗಿ ತಿಳಿಯುತ್ತದೆ.\n\nಅರ್ಜುನ ಉವಾಚ |\nಮದನುಗ್ರಹಾಯ ಪರಮಂ ಗುಹ್ಯಮಧ್ಯಾತ್ಮಸಂಜ್ಞಿತಮ್‌।\nಯಶ್‌ ತ್ವಯೋಕ್ತಂ ವಚಸ್ತೇನ ಮೋಹೋ$ಯಂ ವಿಗತೋ ಮಮ ॥೧॥\n\nಅರ್ಜುನಃ ಉವಾಚ- ಅರ್ಜುನ ಹೇಳಿದನು:\n\nಮತ್‌ ಅನುಗ್ರಹಾಯ ಪರಮಮ್‌ ಗುಹ್ಯಮ್‌ ಅಧ್ಯಾತ್ಮ ಸಂಜ್ಞಿತಮ್‌।\n\nಯತ್‌ ತ್ವಯಾ ಉಕ್ತಮ್‌ ವಚಃ ತೇನ ಮೋಹಃ ಅಯಮ್‌ ವಿಗತಃ ಮಮ -- ನನ್ನ ಮೇಲೆ ದಯೆದೋರಲೆಂದು,\nಅಧ್ಯಾತ್ಮವೆಂಬ ಹಿರಿಯ ಗುಟ್ಟನ್ನು ನೀನು ನುಡಿದೆ. ಆ ನುಡಿಯಿಂದ ನನ್ನೀ ಮಂಕು ಕಳೆಯಿತು.\n\nಅರ್ಜುನ ಹೇಳುತ್ತಾನೆ: “ನನ್ನ ಮೇಲಿನ ಅನುಗ್ರಹದಿಂದ ಅಧ್ಯಾತ್ಮದ ಪರಮ ಗುಹ್ಯವಾದ ವಿಚಾರವನ್ನು ನನಗೆ\nಹೇಳಿದಿ” ಎಂದು. ಇಲ್ಲಿ “ಅನುಗ್ರಹ' ಎಂದರೆ-ತಮ್ಮಿಂದ ಚಿಕ್ಕವರನ್ನು ಸರಿದಾರಿಯಲ್ಲಿ ತಂದು, ಎತ್ತರಕ್ಕೇರಿಸಿ\nಉದ್ಧಾರ ಮಾಡಬೇಕು ಎಂಬ ಹಿರಿಯರ ಇಚ್ಛೆ. “ದಾರಿ ತಪ್ಪಿ ನಡೆಯಲಿದ್ದ ನನ್",
  "11.1": "ಅರ್ಜುನಃ ಉವಾಚ- ಅರ್ಜುನ ಹೇಳಿದನು:\n\nಮತ್‌ ಅನುಗ್ರಹಾಯ ಪರಮಮ್‌ ಗುಹ್ಯಮ್‌ ಅಧ್ಯಾತ್ಮ ಸಂಜ್ಞಿತಮ್‌।\n\nಯತ್‌ ತ್ವಯಾ ಉಕ್ತಮ್‌ ವಚಃ ತೇನ ಮೋಹಃ ಅಯಮ್‌ ವಿಗತಃ ಮಮ -- ನನ್ನ ಮೇಲೆ ದಯೆದೋರಲೆಂದು,\nಅಧ್ಯಾತ್ಮವೆಂಬ ಹಿರಿಯ ಗುಟ್ಟನ್ನು ನೀನು ನುಡಿದೆ. ಆ ನುಡಿಯಿಂದ ನನ್ನೀ ಮಂಕು ಕಳೆಯಿತು.\n\nಅರ್ಜುನ ಹೇಳುತ್ತಾನೆ: “ನನ್ನ ಮೇಲಿನ ಅನುಗ್ರಹದಿಂದ ಅಧ್ಯಾತ್ಮದ ಪರಮ ಗುಹ್ಯವಾದ ವಿಚಾರವನ್ನು ನನಗೆ\nಹೇಳಿದಿ” ಎಂದು. ಇಲ್ಲಿ “ಅನುಗ್ರಹ' ಎಂದರೆ-ತಮ್ಮಿಂದ ಚಿಕ್ಕವರನ್ನು ಸರಿದಾರಿಯಲ್ಲಿ ತಂದು, ಎತ್ತರಕ್ಕೇರಿಸಿ\nಉದ್ಧಾರ ಮಾಡಬೇಕು ಎಂಬ ಹಿರಿಯರ ಇಚ್ಛೆ. “ದಾರಿ ತಪ್ಪಿ ನಡೆಯಲಿದ್ದ ನನ್ನನ್ನು ಸರಿದಾರಿಗೆ ತಂದು ಉದ್ಧಾರ\nಮಾಡಿದಿ” ಎನ್ನುವ ಭಾವವನ್ನು ಅರ್ಜುನ ವ್ಯಕ್ತಪಡಿಸಿದ್ದಾನೆ. ಇಲ್ಲಿ 'ಮತ್‌' ಎನ್ನುವ ಪದ ಬಳಕೆಯಾಗಿದೆ. “ಮತ್‌'\nಎಂದರೆ ಕೇವಲ \"ನನ್ನ ಅಥವಾ ನನಗೆ' ಅನ್ನು ವ ಅರ್ಥವಷ್ಟೇ ಅಲ್ಲ. \"ಮತ್‌' ಎನ್ನು ವುದು ಯತ್‌ ಇದ್ದಂತೆ.\n'ಮಾತೀತಿ ಮತ್‌'-ಅಂದರೆ “ಸಮಸ್ತ ಜ್ಞಾನಿಗಳು' ಅನ್ನುವ ಅರ್ಥವನ್ನು ಕೊಡುತ್ತದೆ. ಆದ್ದರಿಂದ ಮದನುಗ್ರಹ\nಅಂದರೆ “ಸಮಸ್ತ ಜ್ಞಾನಿಗಳ ಉದ್ಧಾರಕ್ಕೋಸ್ಕರ' ಎಂದರ್ಥ. ಭಗವಂತ ಸಮಸ್ತ ಮನುಕುಲಕ್ಕೆ ಈ ಅಪೂರ್ವ\nಸಂದೇಶವನ್ನು ತಲುಪಿಸಲು ಗೀತೆಯನ್ನು ಅರ್ಜುನನಿಗೆ ಉಪದೇಶ ಮಾಡಿ, ಅದನ್ನು ತಾನೇ ವ್ಯಾಸರೂಪನಾಗಿ\nದಾಖಲಿಸಿ ನಮಗೆ ಕೊಟ್ಟ ನೇ ಹೊರತು, ಕೇವಲ ಅರ್ಜುನನಿಗೋಸ್ಕರ ಹೇಳಿದ್ದಲ್ಲ.\n\nಈ ಪ್ರಪಂಚದಲ್ಲಿ ಅತ್ಯಂತ ಗೋಪ್ಯವಾಗಿರಬೇಕಾದ ವಿದ್ಯೆ-ಅಧ್ಯಾತ್ಮ ವಿದ್ಯೆ. ಯಾವಾಗಲೂ ಅಪೂರ್ವ\nವಿಷಯವನ್ನು ಗೋಷ್ಯವಾಗಿಡುತ್ತಾರೆ. ಏಕೆಂದರೆ ಅದು ದುರುಪಯೋಗವಾಗಬಾರದು ಮತ್ತು ಅದರ ಮಹತ್ವ\nತಿಳಿಯದವರಿಗೆ ತಲುಪಬಾರದು. ಅಧ್ಯಾತ್ಮ-ಮನೋವಿಜ್ಞಾನ, ಜೀವವಿಜ್ಞಾನ ಮತ್ತು ಪರಮಾತ್ಮವಿಜ್ಞಾನ.\nಇಂತಹ ಅಪೂರ್ವ ವಿದ್ಯೆಯನ್ನು ಕೃಷ್ಣ ಅರ್ಜುನನ ಮುಂದೆ ತೆರೆದಿಟ್ಟಿರುವುದಕ್ಕೆ ಅರ್ಜುನ ಭಗವಂತನನ್ನು\nಕೊಂಡಾಡುತ್ತಾನೆ ಮತ್ತು ಹೇಳುತ್ತಾನೆ: “ಇದರಿಂದ ನನ್ನೆಲ್ಲಾ ಮಾನಸಿಕ ಗೊಂದಲ ಹೊರಟು ಹೋಗಿ ಮೋಹ\nಕಳೆಯಿತು” ಎಂದು.\n",
  "11.2": "ಭವ ಅಪ್ಯಯೌ ಹಿ ಭೂತಾನಾಮ್‌ ಶ್ರುತ್‌ೌ ವಿಸ್ತರಶಃ ಮಯಾ |\nತ್ವತ್ತಃ ಕಮಲಪತ್ರ ಅಕ್ಷ ಮಾಹಾತ್ಮ್ಯಮ್‌ ಅಪಿ ಚ ಅವ್ಯಯಮ್‌ -- ಜೀವಿಗಳ ಹುಟ್ಟು ಸಾವುಗಳ ಬಿತ್ತರವನ್ನು\nನಾನು ನಿನ್ನಿಂದ ಕೇಳಿದೆ; ಓ ತಾವರೆ ಎಸಳಂಥ ಕಣ್ಣಳವನೇ, ನಿನ್ನ ಅಳಿವಿರದ ಮಹಿಮೆಯನ್ನು ಕೂಡಾ.\n\n“ಜೀವಿಗಳ ಭವ ಮತ್ತು ಅಪ್ಯಯಗಳ ಬಿತ್ತರವನ್ನು ನಾನು ನಿನ್ನಿಂದ ಕೇಳಿದೆ” ಎನ್ನುತ್ತಾನೆ ಅರ್ಜುನ. ಇಲ್ಲಿ ಭವ\nಮತ್ತು ಅಪ್ಯಯ ಎನ್ನುವುದಕ್ಕೆ ಹುಟ್ಟು-ಸಾವು, ಸೃಷ್ಟಿ-ಸಂಹಾರ ಎನ್ನುವ ಅರ್ಥವಲ್ಲದೆ ಇನ್ನೊಂದು ಬಹಳ\nರೋಚಕವಾದ ಅರ್ಥವಿದೆ. ವೇದಕಾಲದ ಖುಷಿಗಳು ಇದನ್ನು ಒಂದು ಹೊಸ ಅರ್ಥದಲ್ಲಿ ಬಳಸುತ್ತಿದ್ದರು.\n“ಪ್ರಭವಾಷ್ಯಯೌ ಭೂತಾನಾಂ” ಎಂದು ಉಪನಿಷತ್ತಿನಲ್ಲಿ ಬರುತ್ತದೆ. ಸುಖಪ್ರಾಪ್ತಿ-ಭವ ಮತ್ತು ದುಃಖನಿವೃತ್ತಿ-\nಅಪ್ಯಯ. ಇದು ಪ್ರಾಚೀನ ಖುಷಿಗಳ ಅರ್ಥ. “ಯಾವ ರೀತಿಯ ನಡೆಯಿಂದ ಸುಖ ಪಡೆಯಬಹುದು, ಯಾವ\nರೀತಿಯ ನಡೆಯಿಂದ ನಮ್ಮ ಬದುಕಿನ ದುಃಖದಿಂದ ಪಾರಾಗಬಹುದು ಎನ್ನುವ ಮೂಲ ಮಂತ್ರವನ್ನು ನಿನ್ನ\nಬಾಯಿಯಿಂದಲೇ ಹೇಳಿದಿ-ಅದನ್ನು ನಾನು ಕಿವಿಯಾರೆ ಕೇಳಿದೆ” ಎನ್ನುತ್ತಾನೆ ಅರ್ಜುನ.\n\nಇಲ್ಲಿ 'ಕಮಲಪತ್ರಾಕ್ಷ' ಎನ್ನುವ ಒಂದು ವಿಶೇಷಣ ಬಳಸಿದ್ದಾರೆ. ಇದನ್ನು ಅರ್ಜುನ ಪ್ರಯೋಗ ಮಾಡುವುದರಲ್ಲಿ\nಒಂದು ವಿಶೇಷವಿದೆ. “ನೀನು ನನ್ನ ಮೇಲೆ ಕಾರುಣ್ಯದ ರಸಧಾರೆಯನ್ನು ಹರಿಸಿದೆಯಲ್ಲಾ ಕೃಷ್ಣ” ಎನ್ನುವ ಭಾವ\nಈ ವಿಶೇಷಣದ ಹಿಂದಿದೆ. “ನಿನ್ನ ಮಹಿಮೆ ಅವ್ಯಯ ಅನಂತವಾಗುಳಿಯುವ ಸಂಪತ್ತು. ಆ ಮಹತ್ತಾದ ಜ್ಞಾನವನ್ನು\nನನಗೆ ಕೊಟ್ಟೆ. ಅತಿ ದುರ್ಲಭವಾದ ನಿನ್ನ ಮಹಿಮೆಯನ್ನು ನನಗೆ ಹೇಳಿದೆ” ಎನ್ನುತ್ತಾನೆ ಅರ್ಜುನ.\n",
  "11.3": "ಏವಮ್‌ ಏತತ್‌ ಯಥಾ ಆತ್ಮ ತ್ವಮ್‌ ಆತ್ಮಾನಮ್‌ ಪರಮೇಶ್ವರ |\nದ್ರಷ್ಟುಮ್‌ ಇಚ್ಛಾಮಿ ತೇ ರೂಪಮ್‌ ಐಶ್ವರಮ್‌ ಪುರುಷೋತ್ತಮ -ಪರಮೇಶ್ವರಾ, ನೀನು ನಿನ್ನ ಬಗೆಗೆ\nಏನಂದೆಯೋ ಅದೆಲ್ಲಾ ನಿಜ. ಓ ಪುರುಷೋತ್ತಮಾ, ಜಗವನಾಳುವ ನಿನ್ನ ರೂಪವನ್ನು ಕಾಣುವ ತವಕ ನನಗೆ.\n\n“ನೀನು ಹೇಳಿದ್ದರಲ್ಲಿ ನನಗೆ ಯಾವ ಸಂಶಯವೂ ಇಲ್ಲ” ಎನ್ನುತ್ತಾನೆ ಅರ್ಜುನ. ಇಲ್ಲಿ ಅರ್ಜುನ ಕೃಷ್ಣನನ್ನು\n'ಪರಮೇಶ್ವರಃ' ಎಂದು ಸಂಬೋಧಿಸಿದ್ದಾನೆ. ಈಶ ಎಂದರೆ ಸಮರ್ಥ. ನಮ್ಮನ್ನು ನಿಯಂತ್ರಿಸುವ ದೇವತೆಗಳು\nಈಶರು. ಅವರನ್ನು ನಿಯಂತ್ರಿಸುವ ಅಂತಃಕರಣ ಹಾಗೂ ಜೀವಕಲಾಭಿಮಾನಿ ದೇವತೆಗಳಾದ ಗರುಡ, ಶೇಷ\nರುದ್ರ ಹಾಗೂ ಬ್ರಹ್ಮ ವಾಯು-ಈಶ್ವರರು. ಈ ತತ್ತ್ವಾಭಿಮಾನಿ ದೇವತೆಗಳ ನಿಯಾಮಕನಾದ, ಎಲ್ಲಕ್ಕಿಂತ\nಎತ್ತರದಲ್ಲಿರುವ, ಎಲ್ಲರ ಒಡೆಯ ಭಗವಂತ ಪರಮೇಶ್ವರಃ. “ನೀನು ಹೇಳಿದ ವಿಚಾರದಲ್ಲಿ ನನಗೆ ಗೊಂದಲವಿಲ್ಲ.\nಏಕೆಂದರೆ ನೀನು ಪರಮೇಶ್ವರಃ, ಆದರೆ ನನಗೆ ಆ ನಿನ್ನ ಸರ್ವಸಾಮರ್ಥ್ಯದಿಂದ ತುಂಬಿದ ರೂಪವನ್ನು ಕಾಣುವ\nತವಕವಾಗುತ್ತಿದೆ” ಎಂದು \"ಭಗವಂತನ ಅದ್ಭುತ ರೂಪವನ್ನು ಕಾಣಬೇಕು' ಎನ್ನುವ ತನ್ನ ಬಯಕೆಯನ್ನು ಅರ್ಜುನ\nಕೃಷ್ಣನ ಮುಂದಿಡುತ್ತಾನೆ.\n\nಇಲ್ಲಿ ಅರ್ಜುನ ಭಗವಂತನನ್ನು 'ಪುರುಷೋತ್ತಮಃ' ಎಂದು ಸಂಬೋಧಿಸಿದ್ದಾನೆ. ಈ ಪದಕ್ಕಿರುವ ವಿಶಿಷ್ಠ\nಅರ್ಥವನ್ನು ಕೃಷ್ಣ ಅಧ್ಯಾಯ ಹದಿನೈದರಲ್ಲಿ(ಅ-೧೫, ಶ್ಲೋ-೧೬-೧೮) ವಿವರವಾಗಿ ವಿವರಿಸುತ್ತಾನೆ. ಲೋಕದಲ್ಲಿ\nಎರಡು ಬಗೆಯ ಪುರುಷರಿದ್ದಾರೆ. ಕ್ಷರಪುರುಷ ಮತ್ತು ಅಕ್ಷರಪುರುಷ. ಬ್ರಹ್ಮಾದಿ ಸಮಸ್ತ ಜೀವರೂ ಕ್ಷರಪುರುಷರು.\nಈ ಚರಾಚರದ ಕೂಟವನ್ನು ಕೂಡಿಸಿಟ್ಟ ಚಿತ್‌ ಪ್ರಕೃತಿಯೇ ಅಕ್ಷರ ಪುರುಷಳೆನಿಸಿದ್ದಾಳೆ-(ಅ-೧೫, ಶ್ಲೋ-೧೭); ಈ\nಎರಡಕ್ಕೂ ಮಿಗಿಲಾದವನು. ಪುರುಷೋತ್ತಮ. ಅವನನ್ನೇ ಪರಮಾತ್ಮ ಎನ್ನುತ್ತಾರೆ. ಅಳಿವಿರದ ಆ\nಪರಮೇಶ್ವರನೇ ಮೂರು ಲೋಕದೊಳಗಿದ್ದು ಸಲಹುತ್ತಾನೆ (ಅ-೧೫, ಶ್ಲೋ-೧೭). ಕ್ಷರವನ್ನು ಮೀರಿ ನಿಂತವನು,\nಅಕ್ಷರಕ್ಕಿಂತಲೂ ಹಿರಿಯನೂ ಆದ ಆ ನಾರಾಯಣ 'ಪುರುಷೋತ್ತಮ'.(ಅ-೧೫, ಶ್ಲೋ-೧೮). “ನಿನ್ನ\nಪುರುಷೋತ್ತಮತ್ವದ ರೂಪವನ್ನು ನಾನು ಕಾಣಬೇಕು” ಎನ್ನುವ ಅಭಿಲಾಷೆಯನ್ನು ಅರ್ಜುನ ಕೃಷ್ಣನ ಮುಂದಿಟ್ಟ.\n",
  "11.4": "ಮನ್ಯಸೇ ಯದಿ ತತ್‌ ಶಕ್ಯಮ್‌ ಮಯಾ ದ್ರಷ್ಟುಮ್‌ ಇತಿ ಪ್ರಭೋ |\n\nಯೋಗೇಶ್ವರ ತತಃ ಮೇ ತ್ವಮ್‌ ದರ್ಶಯ ಆತ್ಮಾನಮ್‌ ಅವ್ಯಯಮ್‌ -ಜಗದೊಡೆಯನೇ,\nಯೋಗಿಗಳೊಡೆಯನೇ, ಅದು ನನ್ನಿಂದ ಕಾಣಲು ಸಾಧ್ಯವೆಂದು ನೀನು ಭಾವಿಸುವುದಾದರೆ, ನಿನ್ನ ಅಳಿವಿರದ\nರೂಪವನ್ನು ನನಗೆ ತೋರಿಸು.\n\nಅರ್ಜುನ ಮುಂದುವರಿದು ಹೇಳುತ್ತಾನೆ. “ನಾನು ಆ ನಿನ್ನ ರೂಪವನ್ನು ನೋಡಲು ಸಾಧ್ಯ ಎಂದು ನೀನು\nಭಾವಿಸುವುದಾದರೆ, ನಿನ್ನ ರೂಪವನ್ನು ನನಗೆ ತೋರಿಸು” ಎಂದು. ಇಲ್ಲಿ ಅರ್ಜುನ ಕೃಷ್ಣನನ್ನು 'ಪ್ರಭೋ' ಎಂದು\nಸಂಬೋಧಿಸಿದ್ದಾನೆ... “ಪ್ರಭು' ಅಂದರೆ ಸಾಮರ್ಥ್ಯ. “ನೋಡುವ ಸಾಮರ್ಥ್ಯ ನನಗಿಲ್ಲದಿದ್ದರೂ, ಆ\nಸಾಮರ್ಥ್ಯವನ್ನು ಕರುಣಿಸಿ ತೋರಿಸುವ ಸಾಮರ್ಥ್ಯ ನಿನಗಿದೆ” ಎನ್ನುವುದು ಈ ಸಂಬೋಧನೆಯ ಹಿಂದಿರುವ\nಭಾವ. “ಏಕೆಂದರೆ ನೀನು ಯೋಗೇಶ್ವರಃ” ಎನ್ನು ತ್ತಾನೆ ಅರ್ಜುನ. ಯೋಗ ಅಂದರೆ ಉಪಾಯ. “ನನಗೆ ಹೇಗೆ\nನಿನ್ನ ರೂಪವನ್ನು ತೋರಿಸಬೇಕು ಎನ್ನುವ ಉಪಾಯ ಕೂಡಾ ನಿನಗೆ ತಿಳಿದಿದೆ. ನೀನು ಎಲ್ಲಾ\nಉಪಾಯ(ಯೋಗ)ಗಳ ಸ್ವಾಮಿ. ಆದ್ದರಿಂದ ಅಳಿವಿರದ, ನಿತ್ಯವಾಗಿರುವ ಆ ನಿನ್ನ ರೂಪವನ್ನು ನನಗೆ\nತೋರಿಸು” ಎಂದು ಅರ್ಜುನ ಕೃಷ್ಣನನ್ನು ಕೇಳಿಕೊಳ್ಳುತ್ತಾನೆ.",
  "11.5": "ಭಗವಾನ್‌ ಉವಾಚ-ಭಗವಂತ ಹೇಳಿದನು:\n\nಪಶ್ಯ ಮೇ ಪಾರ್ಥ ರೂಪಾಣಿ ಶತಶಃ ಅಥ ಸಹಸ್ರಶಃ ।\n\nನಾನಾವಿಧಾನಿ ದಿವ್ಯಾನಿ ನಾನಾ ವರ್ಣ ಆಕೃತೀನಿ ಚ -ನೋಡು ಪಾರ್ಥಾ, ನನ್ನ ರೂಪಗಳನ್ನು . ನೂರಾರು,\nಸಾವಿರಾರು; ಬಗೆಬಗೆಯವು; ಹೊಳೆಯುವಂಥವ); ಹಲವು ಬಣ್ಣ-ಆಕಾರದವು.\n\nನಿನ್ನ ರೂಪವನ್ನು ತೋರು ಎಂದು ಅರ್ಜುನ ಏಕವಚನದಲ್ಲಿ ಕೇಳಿದರೆ ಕೃಷ್ಣ ಬಹುವಚನದಲ್ಲಿ ಹೇಳುತ್ತಾನೆ\n“ನೋಡು ನನ್ನ ರೂಪಗಳನ್ನು” ಎಂದು. ಭಗವಂತನ ಎಲ್ಲಾ ರೂಪಗಳೂ ಒಂದೇ. ಮೂಲ ರೂಪಕ್ಕೂ ಅವತಾರ\nರೂಪಕ್ಕೂ ಭೇದವಿಲ್ಲ. “ನೀನು ಹಿಂದೆಂದೂ ಕಾಣದ ಅತ್ಯದ್ಭುತವಾದ ನನ್ನ ನೂರಾರು, ಸಾವಿರಾರು,\nಬಗೆಬಗೆಯ, ಹೊಳೆಯುವಂತಹ, ಹಲವು ಬಣ್ಣ ಮತ್ತು ಆಕಾರದ ರೂಪಗಳನ್ನು ನೋಡು” ಎಂದು ಕೃಷ್ಣ\nಅರ್ಜುನನಿಗೆ ಹೇಳುತ್ತಾನೆ. ಇಲ್ಲಿ ಕೃಷ್ಣ ಅರ್ಜುನನನ್ನು \"ಪಾರ್ಥ' ಎಂದು ಸಂಬೋಧಿಸಿದ್ದಾನೆ. ನಿಜವಾದ\nವೇದಾರ್ಥ ತಿಳಿದು ವೇದಾರ್ಥಭೂತನಾದ ಭಗವಂತನೆಡೆಗೆ ಪಯಣ ಹೊರಟವರು 'ಪಾರ್ಥರು',",
  "11.6": "ಪಶ್ಯ ಆದಿತ್ಯಾನ್‌ ವಸೂನ್‌ ರುದ್ರಾನ್‌ ಅಶ್ವಿನೌ ಮರುತಃ ತಥಾ ।\nಬಹೂನಿ ಅದೃಷ್ಟ ಪೂರ್ವಾಣಿ ಪಶ್ಯ ಆಶ್ಚರ್ಯಾಣಿ ಭಾರತ -- ನೋಡು-ಆದಿತ್ಯರನ್ನು , ವಸುಗಳನ್ನು, ರುದ್ರರನ್ನು,\nಅಶ್ವಿಗಳನ್ನು ಮತ್ತು ಮರುತ್ತುಗಳನ್ನು. ಓ ಭಾರತಾ, ನೋಡು ಹಿಂದೆಂದೂ ಕಂಡಿರದ ಹಲವು ಅಚ್ಚರಿಗಳನ್ನು.\n\n“ಜಗತ್ತಿನಲ್ಲಿರುವ ಎಲ್ಲಾ ಆದಿತ್ಯರು(ದ್ವಾದಶಾದಿತ್ಯರು), ವಸುಗಳು (ಅಷ್ಟ ವಸುಗಳು), ರುದ್ರರು (ಏಕಾದಶ\nರುದ್ರರು), ಅಶ್ವಿಗಳು(ಇಬ್ಬರು), ಮರುತ್ತುಗಳು(ನಲವತ್ತೊಂಬತ್ತು)-ಎಲ್ಲರನ್ನೂ ನೋಡು. ನೀನು ಹಿಂದೆಂದೂ\nಕಂಡು ಕೇಳರಿಯದ ಅತ್ಯದ್ಭುತ ಅಚ್ಚರಿಯನ್ನು ನೋಡು?” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಇಲ್ಲಿ ಕೃಷ್ಣ ಅರ್ಜುನನನ್ನು 'ಭಾರತ'\nಎಂದು ಸಂಬೋಧಿಸಿದ್ದಾನೆ. ಐತರೇಯ ಬ್ರಾಹ್ಮಣದಲ್ಲಿ \"ವಾಯರ್ವಾವ ಭರತಃ' ಎನ್ನು ವ ಒಂದು ಮಾತಿದೆ. ಸದಾ\nಭಗವಂತನಲ್ಲಿ ನಿರತನಾದ ವಾಯು ದೇವರಿಗೆ ಭರತ ಎಂದು ಹೆಸರು. ಆದ್ದರಿಂದ ಇಲ್ಲಿ 'ಭಾರತ' ಎಂದರೆ\n“ಭೀಮ(ಪ್ರಾಣತತ್ವ)ನ ತಮ್ಮ' ಎನ್ನುವ ಅರ್ಥವನ್ನು ಕೊಡುತ್ತದೆ. [ಸದಾ ಭಗವಂತನಿಗೆ ಅತೀ ಹತ್ತಿರವಿರುವ\nಹನುಮಂತ ಅಥವಾ ಪ್ರಾಣತತ್ವದ ಉಪಾಸನೆ ಭಗವಂತನನ್ನು ತಿಳಿಯುವ ಸುಲಭ ಸಾಧನ.]\n\nಇಹೈಕಸ್ಸಂ ಜಗತ್‌ ಕೃತ್ಸ 0 ಪಶ್ನಾದ್ಯ ಸಚರಾಚರಮ್‌ ।\nಕಿ ೨ 2)\n\nನ\n\nಮಮ ದೇಹೇ ಗುಡಾಕೇಶ ಯಚ್ಚಾನ್ಯದ್‌ ದ್ರಷ್ಟುಮಿಚ್ಛಸಿ 1೭॥\n\nಇಹ ಏಕ ಸ್ಫಮ್‌ ಜಗತ್‌ ಕೃತ್ಸ್ನಮ್‌ ಪಶ್ಯ ಅದ್ಯ ಸ ಚರ ಅಚರಮ್‌ ।\n\nಮಮ ದೇಹೇ ಗುಡಾಕೇಶ ಯತ್‌ ಚ ಅನ್ಯತ್‌ ದ್ರಷ್ಟುಮ್‌ ಇಚ್ಛಸಿ-ಇಲ್ಲಿ ನೋಡೀಗ, ನನ್ನ ಮೈಯಲ್ಲಿ\nಚರಾಚರಗಳಿಂದ ಕೂಡಿದ ಇಡಿಯ ಜಗತ್ತು ಒಂದುಗೂಡಿದ್ದನ್ನು. ಓ ಗುಡಾಕೇಶಾ, ಇನ್ನೇನು ನೋಡ\nಬಯಸುವೆಯೋ-ಅದನ್ನೆಲ್ಲಾ ನೋಡು.\n\n“ನನ್ನ ದೇಹವನ್ನು ಆಶ್ರಯಿಸಿಕೊಂಡಿರುವ ಸಮಸ್ತ ವಿಶ್ವವನ್ನು ನೋಡು. ಬ್ರಹ್ಮಾಂಡದೊಳಗೆ ಏನೇನಿದೆಯೋ\nಅದೆಲ್ಲವೂ ಇಲ್ಲಿದೆ. ಚೇತನ, ಅಚೇತನ, ಚಲಿಸುವ, ಚಲಿಸದ, ಎಲ್ಲವೂ. ನಿನಗೆ ಏನು ನೋಡಬೇಕು ಎಂದು ನಿನ್ನ\nಮನಸ್ಸು ಬಯಸುತ್ತದೆಯೋ ಅದನ್ನು ನೋಡು” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಇಲ್ಲಿ ಕೃಷ್ಣ ಅರ್ಜುನನನ್ನು ಗುಡಾಕೇಶ ಎಂದು\nಸಂಬೋಧಿಸುತ್ತಾನೆ. ಅಜ್ಞಾನ, ಆಲಸ್ಯ ಮತ್ತು ನಿದ್ದೆಯನ್ನು ಗೆದ್ದವ ಗುಡಾಕೇಶ.\n\nಇಲ್ಲಿ ಒಂದೊಂದು ಶ್ಲೋಕದಲ್ಲಿ ಒಂದೊಂದು ವಿಶೇಷಣ ಬಳಸಿದ್ದಾರೆ. ಈ ವಿಶೇಷಣದ ಹಿಂದೆ ಇರುವ ಅರ್ಥವನ್ನು\nನೋಡಿದಾಗ ತಿಳಿಯುವುದೇನೆಂದರೆ -ನಮಗೆ ಭಗವಂತ ತಿಳಿಯಬೇಕಾದರೆ ನಾವೂ ಕೂಡಾ ಪಾರ್ಥ, ಭಾರತ,\nಗುಡಾಕೇಶರಾಗಬೇಕು. ಎನ್ನುವುದು. ವೇದಾರ್ಥ ತಿಳಿದು ವೇದಾರ್ಥಭೂತನಾದ ಭಗವಂತನೆಡೆಗೆ\nಪಯಣ(ಪಾರ್ಥ), ಪ್ರಾಣತತ್ವದ ಯಉಪಾಸನೆೇ(ಭಾರತ), ಅಜ್ಞಾನ, ಆಲಸ್ಯ ಗೆದ್ದು ಭಗವಂತನ\nಚಿಂತನೆ(ಗುಡಾಕೇಶ) ಮಾಡಿದಾಗ- ಆ ಭಗವಂತನ ರೂಪ ನಮಗೆ ತಿಳಿದೀತು.",
  "11.7": "ಪಶ್ಯ ಆದಿತ್ಯಾನ್‌ ವಸೂನ್‌ ರುದ್ರಾನ್‌ ಅಶ್ವಿನೌ ಮರುತಃ ತಥಾ ।\nಬಹೂನಿ ಅದೃಷ್ಟ ಪೂರ್ವಾಣಿ ಪಶ್ಯ ಆಶ್ಚರ್ಯಾಣಿ ಭಾರತ -- ನೋಡು-ಆದಿತ್ಯರನ್ನು , ವಸುಗಳನ್ನು, ರುದ್ರರನ್ನು,\nಅಶ್ವಿಗಳನ್ನು ಮತ್ತು ಮರುತ್ತುಗಳನ್ನು. ಓ ಭಾರತಾ, ನೋಡು ಹಿಂದೆಂದೂ ಕಂಡಿರದ ಹಲವು ಅಚ್ಚರಿಗಳನ್ನು.\n\n“ಜಗತ್ತಿನಲ್ಲಿರುವ ಎಲ್ಲಾ ಆದಿತ್ಯರು(ದ್ವಾದಶಾದಿತ್ಯರು), ವಸುಗಳು (ಅಷ್ಟ ವಸುಗಳು), ರುದ್ರರು (ಏಕಾದಶ\nರುದ್ರರು), ಅಶ್ವಿಗಳು(ಇಬ್ಬರು), ಮರುತ್ತುಗಳು(ನಲವತ್ತೊಂಬತ್ತು)-ಎಲ್ಲರನ್ನೂ ನೋಡು. ನೀನು ಹಿಂದೆಂದೂ\nಕಂಡು ಕೇಳರಿಯದ ಅತ್ಯದ್ಭುತ ಅಚ್ಚರಿಯನ್ನು ನೋಡು?” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಇಲ್ಲಿ ಕೃಷ್ಣ ಅರ್ಜುನನನ್ನು 'ಭಾರತ'\nಎಂದು ಸಂಬೋಧಿಸಿದ್ದಾನೆ. ಐತರೇಯ ಬ್ರಾಹ್ಮಣದಲ್ಲಿ \"ವಾಯರ್ವಾವ ಭರತಃ' ಎನ್ನು ವ ಒಂದು ಮಾತಿದೆ. ಸದಾ\nಭಗವಂತನಲ್ಲಿ ನಿರತನಾದ ವಾಯು ದೇವರಿಗೆ ಭರತ ಎಂದು ಹೆಸರು. ಆದ್ದರಿಂದ ಇಲ್ಲಿ 'ಭಾರತ' ಎಂದರೆ\n“ಭೀಮ(ಪ್ರಾಣತತ್ವ)ನ ತಮ್ಮ' ಎನ್ನುವ ಅರ್ಥವನ್ನು ಕೊಡುತ್ತದೆ. [ಸದಾ ಭಗವಂತನಿಗೆ ಅತೀ ಹತ್ತಿರವಿರುವ\nಹನುಮಂತ ಅಥವಾ ಪ್ರಾಣತತ್ವದ ಉಪಾಸನೆ ಭಗವಂತನನ್ನು ತಿಳಿಯುವ ಸುಲಭ ಸಾಧನ.]\n\nಇಹೈಕಸ್ಸಂ ಜಗತ್‌ ಕೃತ್ಸ 0 ಪಶ್ನಾದ್ಯ ಸಚರಾಚರಮ್‌ ।\nಕಿ ೨ 2)\n\nನ\n\nಮಮ ದೇಹೇ ಗುಡಾಕೇಶ ಯಚ್ಚಾನ್ಯದ್‌ ದ್ರಷ್ಟುಮಿಚ್ಛಸಿ 1೭॥\n\nಇಹ ಏಕ ಸ್ಫಮ್‌ ಜಗತ್‌ ಕೃತ್ಸ್ನಮ್‌ ಪಶ್ಯ ಅದ್ಯ ಸ ಚರ ಅಚರಮ್‌ ।\n\nಮಮ ದೇಹೇ ಗುಡಾಕೇಶ ಯತ್‌ ಚ ಅನ್ಯತ್‌ ದ್ರಷ್ಟುಮ್‌ ಇಚ್ಛಸಿ-ಇಲ್ಲಿ ನೋಡೀಗ, ನನ್ನ ಮೈಯಲ್ಲಿ\nಚರಾಚರಗಳಿಂದ ಕೂಡಿದ ಇಡಿಯ ಜಗತ್ತು ಒಂದುಗೂಡಿದ್ದನ್ನು. ಓ ಗುಡಾಕೇಶಾ, ಇನ್ನೇನು ನೋಡ\nಬಯಸುವೆಯೋ-ಅದನ್ನೆಲ್ಲಾ ನೋಡು.\n\n“ನನ್ನ ದೇಹವನ್ನು ಆಶ್ರಯಿಸಿಕೊಂಡಿರುವ ಸಮಸ್ತ ವಿಶ್ವವನ್ನು ನೋಡು. ಬ್ರಹ್ಮಾಂಡದೊಳಗೆ ಏನೇನಿದೆಯೋ\nಅದೆಲ್ಲವೂ ಇಲ್ಲಿದೆ. ಚೇತನ, ಅಚೇತನ, ಚಲಿಸುವ, ಚಲಿಸದ, ಎಲ್ಲವೂ. ನಿನಗೆ ಏನು ನೋಡಬೇಕು ಎಂದು ನಿನ್ನ\nಮನಸ್ಸು ಬಯಸುತ್ತದೆಯೋ ಅದನ್ನು ನೋಡು” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಇಲ್ಲಿ ಕೃಷ್ಣ ಅರ್ಜುನನನ್ನು ಗುಡಾಕೇಶ ಎಂದು\nಸಂಬೋಧಿಸುತ್ತಾನೆ. ಅಜ್ಞಾನ, ಆಲಸ್ಯ ಮತ್ತು ನಿದ್ದೆಯನ್ನು ಗೆದ್ದವ ಗುಡಾಕೇಶ.\n\nಇಲ್ಲಿ ಒಂದೊಂದು ಶ್ಲೋಕದಲ್ಲಿ ಒಂದೊಂದು ವಿಶೇಷಣ ಬಳಸಿದ್ದಾರೆ. ಈ ವಿಶೇಷಣದ ಹಿಂದೆ ಇರುವ ಅರ್ಥವನ್ನು\nನೋಡಿದಾಗ ತಿಳಿಯುವುದೇನೆಂದರೆ -ನಮಗೆ ಭಗವಂತ ತಿಳಿಯಬೇಕಾದರೆ ನಾವೂ ಕೂಡಾ ಪಾರ್ಥ, ಭಾರತ,\nಗುಡಾಕೇಶರಾಗಬೇಕು. ಎನ್ನುವುದು. ವೇದಾರ್ಥ ತಿಳಿದು ವೇದಾರ್ಥಭೂತನಾದ ಭಗವಂತನೆಡೆಗೆ\nಪಯಣ(ಪಾರ್ಥ), ಪ್ರಾಣತತ್ವದ ಯಉಪಾಸನೆೇ(ಭಾರತ), ಅಜ್ಞಾನ, ಆಲಸ್ಯ ಗೆದ್ದು ಭಗವಂತನ\nಚಿಂತನೆ(ಗುಡಾಕೇಶ) ಮಾಡಿದಾಗ- ಆ ಭಗವಂತನ ರೂಪ ನಮಗೆ ತಿಳಿದೀತು.",
  "11.8": "ನ ತು ಮಾಮ್‌ ಶಕ್ಯಸೇ ದ್ರಷ್ಟುಮ್‌ ಅನೇನ ಏವ ಸ್ವ ಚಕ್ಷುಷಾ ।\nದಿವ್ಯಮ್‌ ದದಾಮಿ ತೇ ಚಕ್ಷುಃ ಪಶ್ಯ ಮೇ ಯೋಗಮ್‌ ಐಶ್ವರಮ್‌--ಆದರೆ ನಿನ್ನ ಈ ಹೊರಗಣ್ಣಿಂದಲೇ\nನೋಡಲಾರೆ ನನ್ನನ್ನು. ನೀಡುತ್ತೇನೆ ನಿನಗೆ ದಿವ್ಯದ ಒಳಗಣ್ಣು. ನೋಡು ಜಗವನಾಳುವ ನನ್ನಳವನ್ನು.\n\nಭಗವಂತನ ರೂಪವನ್ನು ಈ ನಮ್ಮ ಹೊರಗಣ್ಣಿನಿಂದ ಕಾಣಲು ಸಾಧ್ಯವಿಲ್ಲ. ಸ್ವರೂಪಭೂತನಾದ ಆ\nಭಗವಂತನನ್ನು ನಾವು ನಮ್ಮ ಸ್ವರೂಪಭೂತವಾದ ಕಣ್ಣಿನಿಂದ ಮಾತ್ರ ನೋಡಲು ಸಾಧ್ಯ. ಇಲ್ಲಿ ಕೃಷ್ಣ\nಅರ್ಜುನನಿಗೆ ಆತನ ಸ್ವರೂಪಭೂತವಾದ ಕಣ್ಣಿನಿಂದ ಸರ್ವಸಮರ್ಥ ಭಗವಂತನನ್ನು ನೋಡುವ ಸೌಭಾಗ್ಯವನ್ನು\nಕರುಣಿಸುತ್ತಾನೆ.",
  "11.9": "ಸಂಜಯಃ ಉವಾಚ-ಸಂಜಯ ಹೇಳಿದನು:\n\nಏವಮ್‌ ಉಕ್ತ್ವಾ ತತಃ ರಾಜನ್‌ ಮಹಾಯೋಗೇಶ್ವರೋ ಹರಿಃ |\n\nದರ್ಶಯಾಮ್‌ ಆಸ ಪಾರ್ಥಾಯ ಪರಮಮ್‌ ರೂಪಮ್‌ ಐಶ್ವರಮ್‌ -ಅರಸನೇ, ಹಿರಿಯ ಶಕ್ತಿಗಳ ಒಡೆಯನಾದ\nಹರಿ ಹೀಗೆ ನುಡಿದು, ಅರ್ಜುನನಿಗೆ ತೋರಿಸಿದನು ಜಗವನಾಳುವ ಹಿರಿಯ ರೂಪವನ್ನು.\n\nವ್ಯಾಸರಿಂದ ದಿವ್ಯ ದೃಷ್ಟಿ ಪಡೆದು, ಯುದ್ಧರಂಗದಲ್ಲಿ ನಡೆಯುತ್ತಿರುವ ಘಟನೆಗಳ ವಿವರಣೆಯನ್ನು ಧೃತರಾಷ್ಟ್ರನಿಗೆ\nಕೊಡುತ್ತಿರುವ ಸಂಜಯ ಕೂಡಾ ಭಗವಂತನ ವಿಶ್ವರೂಪವನ್ನು ಕಾಣುತ್ತಾನೆ. ಆತ ಧೃತರಾಷ್ಟ್ರನಲ್ಲಿ ಹೇಳುತ್ತಾನೆ:\n“ಓ ರಾಜನ್‌, ಈ ರೀತಿ ಹೇಳಿ ಮಹಾಯೋಗೇಶ್ವರ ಹರಿಯು ತನ್ನ ಹಿರಿಯರೂಪವನ್ನು ತೋರಿದನು” ಎಂದು.\nಇಲ್ಲಿ ಬಳಕೆಯಾಗಿರುವ “ತತಃ' ಅನ್ನುವ ಪದ ಈ ಶ್ಲೋಕದಲ್ಲಿ ವಿಶೇಷ ಅರ್ಥವನ್ನು ಕೊಡುತ್ತದೆ. ಅರ್ಜುನನು ದಿವ್ಯ\nದೃಷ್ಟಿ ಸಂಪನ್ನನಾದ್ದರಿಂದ; ದಿವ್ಯರೂಪ ದರ್ಶನ ನೋಡುವ ಅಧಿಕಾರ ಸಂಪನ್ನನಾದ್ದರಿಂದ; ಎಲ್ಲಾ ಕಡೆ\nತುಂಬಿರುವ ಭಗವಂತ, ತನ್ನ ವಿಶ್ವರೂಪವನ್ನು ಆತನಿಗೆ ತೋರಿದ-ಎನ್ನುವ ಭಾವವನ್ನು ಈ ಪದ ಕೊಡುತ್ತದೆ.\nಬ್ರಹ್ಮಾದಿ ಸರ್ವ ದೇವತೆಗಳಿಗೂ ಒಡೆಯನಾದ ಭಗವಂತನನ್ನು ಸಂಜಯ ಇಲ್ಲಿ ಮಹಾಯೋಗೇಶ್ವರಃ ಎಂದು\nಸಂಬೋಧಿಸಿದ್ದಾನೆ. ಇಲ್ಲಿ ಬಳಸಿರುವ “ಹರಿಃ ಎನ್ನುವ ಪದ ಭಗವಂತನ ಸರ್ವಗತತ್ವವನ್ನು ವಿವರಿಸುವ ಪದ.\nಯಾರು ಯಾವ ದೇವತಾ ಮುಖದಲ್ಲಿ ಆಹುತಿ ಕೊಟ್ಟರೂ ಅದನ್ನು ಮೊದಲು ಪಡೆಯುವ ಭಗವಂತ ಹರಿಃ.\nಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ಸಂಜಯ ತಾನು ಕಂಡ ಭಗವಂತನ ವಿಶ್ವರೂಪದ ವರ್ಣನೆ ಮಾಡುತ್ತಾನೆ.\n\nಅನೇಕವಕ್ರನಯನಮನೇಕಾದ್ಳು ತದರ್ಶನಮ್‌ |\nಅನೇಕದಿವ್ಯಾಭರಣಂ ದಿವ್ಯಾನೇಕೋದ್ಯತಾಯುಧಮ್‌",
  "11.10": "ದಿವ್ಯಮಾಲ್ಯಾಂಬರಧರಂ ದಿವ್ಯಗಂಧಾನುಲೇಪನಮ್‌ |\nಸರ್ವಾಶ್ಚರ್ಯಮಯಂ ದೇವಮನಂತಂ ವಿಶ್ವತೋಮುಖಮ್‌",
  "11.11": "ಅನೇಕ ವಕ್ರ ನಯನಮ್‌ ಅನೇಕ ಅದ್ಭುತ ದರ್ಶನಮ್‌ |\n\nಅನೇಕ ದಿವ್ಯ ಆಭರಣಮ್‌ ದಿವ್ಯ ಅನೇಕ ಉದ್ಯತ ಆಯುಧಮ್‌ ॥\n\nದಿವ್ಯ ಮಾಲ್ಯಾ ಅಂಬರ ಧರಮ್‌ ದಿವ್ಯ ಗಂಧ ಅನುಲೇಪನಮ್‌ |\n\nಸರ್ವ ಆಶ್ಚರ್ಯಮಯಮ್‌ ದೇವಮ್‌ ಅನಂತಮ್‌ ವಿಶ್ವತೋಮುಖಮ್‌ -ಎಣಿಕೆಯಿರದ ಬಾಯಿ ಕಣ್ಣುಗಳ ರೂಪ.\nಎಣಿಕೆಯಿರದ ಅಚ್ಚರಿಯ ನೋಟಗಳ ರೂಪ. ಎಣಿಕೆಯಿರದ ಚೆಲುವಾಭರಣಗಳ ರೂಪ. ಎಣಿಕೆಯಿರದ\nಹೊಳೆಯುವಾಯುಧಗಳನ್ನು ಮೇಲೆತ್ತಿ ಹಿಡಿದ ರೂಪ. ಹೊಳೆವ ಹೂದಂಡೆಗಳನ್ನಿಟ್ಟ ಉಡಿಗೆಗಳ ತೊಟ್ಟ ರೂಪ.\nಹೊಳೆವ ಗಂಧ ಬಳಿದ ರೂಪ. ಎಲ್ಲಾ ಅಚ್ಚರಿಗಳ ಸೆಲೆ. ಎಲ್ಲೆಡೆಯೂ ತುಂಬಿ ತುದಿಯಿರದ ರೂಪ.\n\nಕೃಷ್ಣ ನಮ್ಮೆಲ್ಲರಂತೆ ಮನುಷ್ಯರ ಆಕಾರದಲ್ಲಿ ಕಾಣಿಸಿಕೊಳ್ಳುತ್ತಿದ್ದ. ಆದರೆ ಈ ಕ್ಷಣದಲ್ಲಿ ಎಲ್ಲಿ ನೋಡಿದರಲ್ಲಿ ಕೃಷ್ಣನ\nಮುಖ, ಅಲ್ಲಿ ಸೇರಿರುವ ಪ್ರತಿಯೊಂದು ಜೀವಿಯ ಒಳಗೆ, ಹೊರಗೆ ಎಲ್ಲೆಲ್ಲೂ ಕೇವಲ ಕೃಷ್ಣನ ಮುಖ ಕಾಣುತ್ತಿದೆ.\nಸಂಜಯನಿಗೆ ಅಲ್ಲಿ ಆನೆ, ಕುದುರೆ, ಸೈನಿಕರು ಕಾಣಿಸಲಿಲ್ಲ. ಬದಲಿಗೆ ಎಲ್ದೆಡೆ, ಎಲ್ಲರೊಳಗೆ ತುಂಬಿರುವ ಆ\nಭಗವಂತ ಕಾಣಿಸಿಕೊಂಡ. ಭಗವಂತನ ಈ ರೂಪವನ್ನು ವರ್ಣಿಸುವುದು ಅಸಾಧ್ಯ. ಇದನ್ನು ಕೇವಲ ನೋಡಿ\nಅನುಭವಿಸಬೇಕು. ಅದೊಂದು ಅಚ್ಚರಿ. ಸರ್ವಾಭರಣಗಳಿಂದ ಶೋಭಿಸುವ, ದಿವ್ಯವಾದ ಆಯುಧಗಳನ್ನು\nಹಿಡಿದಿರುವ, ಹೂವಿನ ಮಾಲೆಗಳನ್ನಿಟ್ಟ ಉಡುಪನ್ನು ತೊಟ್ಟ, ಹೊಳೆವ ಗಂಧ ಬಳಿದ, ಸರ್ವಾಶ್ಚರ್ಯ ಸ್ವರೂಪ,\nವಿಸ್ಮಯ ಮೂರ್ತಿ ಭಗವಂತ ಯುದ್ಧರಂಗದಲ್ಲಿ ತನ್ನ ವಿಶ್ವರೂಪವನ್ನು ತೋರಿದ.\n",
  "11.12": "ದಿವಿ ಸೂರ್ಯ ಸಹಸ್ರಸ್ಯ ಭವೇತ್‌ ಯುಗಪತ್‌ ಉತ್ಸಿತಾ |\nಯದಿ ಭಾಃ ಸದೃಶೀ ಸಾ ಸ್ಯಾತ್‌ ಭಾಸ ತಸ್ಯ ಮಹಾತ್ಮನಃ - ಸಾವಿರ ಸಾವಿರ ಸೂರ್ಯರು ಒಮ್ಮೆಲೇ ಮುಗಿಲಲ್ಲಿ\nಮೂಡಿಬಂದರೆ, ಅಂತಹ ಬೆಳಕು ಆ ಮಹಾತ್ಮನ ಬೆಳಕಿಗೆ ಸರಿಗಟ್ಟಿತೇನೊ !\n\nಸಂಜಯ ಹೇಳುತ್ತಾನೆ: “ಸಾವಿರಾರು ಸೂರ್ಯರು ಆಕಾಶದಲ್ಲಿ ಒಮ್ಮೆಗೇ ಉದಿಸಿದರೆ ಎಷ್ಟು\nಪ್ರಕಾಶಮಾನವಾಗಿರುತ್ತದೋ, ಅಂತಹ ಪ್ರಕಾಶಮಾನನಾಗಿ ಭಗವಂತ ಕಾಣಿಸಿದ” ಎಂದು. ಯೋಗಿಗಳಿಗೆ\nಭಗವಂತ ಒಳಗಣ್ಣಿನಲ್ಲಿ ಸಾವಿರ ಸೂರ್ಯರು ಏಕಕಾಲದಲ್ಲಿ ಉದಯಿಸಿದರೆ ಎಷ್ಟು ಪ್ರಖರವಾಗಿರುತ್ತದೋ ಅಷ್ಟು\nಪ್ರಖರವಾಗಿ ಕಾಣಿಸುತ್ತಾನೆ. ಆದರೆ “ಚಂದ್ರಾಂಶು'ವಾದ ಭಗವಂತ ಅಷ್ಟೇ ತಂಪು ಮತ್ತು ಅಹ್ಲಾದಮಯ.\nಭಗವಂತ ಸೂರ್ಯನಂತೆ ಪ್ರಖರ ಆದರೆ ಚಂದ್ರನಂತೆ ತಂಪು. ಇಷ್ಟು ಪ್ರಕಾಶಮಾನನಾಗಿರುವ ಭಗವಂತನ\nರೂಪವನ್ನು ಯಾರೂ ಎಂದೆಂದೂ ತಮ್ಮ ಹೊರಗಟಣ್ಣಿನಿಂದ ಕಾಣಲು ಸಾಧ್ಯವಿಲ್ಲ.",
  "11.13": "ತತ್ರ ಏಕಸ್ಗಮ್‌ ಜಗತ್‌ ಕೃತ್ಸ _ಮ್‌ ಪ್ರವಿಭಕ್ತಮ್‌ ಅನೇಕಧಾ ।\nಅಪಶ್ಯತ್‌ ದೇವದೇವಸ್ಯ ಶರೀರೇ ಪಾಂಡವಃ ತದಾ -ಅರ್ಜುನ ಕಂಡನಾಗ ಬಗೆಬಗೆಯಿಂದ ವಿಂಗಡಗೊಂಡ\nಇಡಿಯ ಪೊಡವಿ ಅಲ್ಲಿ, ದೇವದೇವನ ಮೈಯಲ್ಲಿ ಒಂದುಗೂಡಿದ್ದನ್ನು\n\nಭಗವಂತ ಅರ್ಜುನನಿಗೆ ರಣರಂಗದಲ್ಲಿ ತೋರಿದ ವಿಶ್ವರೂಪ ತುಂಬಾ ವಿಶಿಷ್ಟವಾದದ್ದು. ಮಧ್ವಾಚಾರ್ಯರು\nಹೇಳುವಂತೆ ಅರ್ಜುನನಿಗೆ ವಿಶ್ವರೂಪ ದರ್ಶನವಾದಾಗ, ಪ್ರಪಂಚದಲ್ಲಿ ಭಗವಂತನ ವಿಶ್ವರೂಪ ದರ್ಶನ\n\nಕಾಣುವ ಅರ್ಹತೆಯುಳ್ಳ ಎಲ್ಲರಿಗೂ ಈ ದರ್ಶನವಾಗಿತ್ತು. [ಮೂರು ಲೋಕದಲ್ಲಿರುವ, ಅರ್ಹತೆಯುಳ್ಳ ಸಮಸ್ತ\nಜೀವಿಗಳಿಗೂ ಭಗವಂತನ ಈ ವಿಶೇಷ ದರ್ಶನವಾಗಿದೆ ಎನ್ನುವ ಮಾತು ಮುಂದೆ ಈ ಅಧ್ಯಾಯದಲ್ಲಿ ಬರುತ್ತದೆ].\nಅರ್ಜುನನಿಗೆ ಇಲ್ಲಿ ಕಾಣಿಸಿದ್ದು ಕೇವಲ ಎಲ್ಲೆಡೆ ತುಂಬಿರುವ ಭಗವಂತ ಮಾತ್ರವಲ್ಲ, ಆತನೊಳಗೆ ತುಂಬಿರುವ\nಪ್ರಪಂಚ ಕೂಡಾ. [ಇಲ್ಲಿ ಭಗವಂತನೊಳಗೆ ವಿಶ್ವವನ್ನು ಕಾಣುವುದು ಅಂದರೆ ಧ್ಯಾನದಲ್ಲಿ ಪರಮಾತ್ಮನನ್ನು,\nಆತನಿಂದ ಸೃಷ್ಟವಾದ ಸೃಷ್ಟಿಯನ್ನು ಕಂಡಂತೆ. ಸತ್ವದಿಂದ ಸ್ವಚ್ಛವಾದ ಮನಸ್ಸುಳ್ಳ ಅರ್ಜುನ(ಪಾಂಡವ), ತನ್ನ\nದಿವ್ಯ ದೃಷ್ಟಿಯಿಂದ ಭಗವಂತನಲ್ಲಿ ತುಂಬಿರುವ ಇಡೀ ವಿಶ್ವವನ್ನು ಸ್ಪಷ್ಟವಾಗಿ ಕಂಡ]\n",
  "11.14": "ತತಃ ಸಃ ವಿಸ್ಮಯ ಅವಿಷ್ಣಃ ಹೃಷ್ಟರೋಮಾ ಧನಂಜಯಃ ।\nಪ್ರಣಮ್ಯ ಶಿರಸಾ ದೇವಮ್‌ ಕೃತಾಂಜಲಿಃ ಅಭಾಷತ -ಬಳಿಕ ಬೆರಗಲ್ಲಿ ಮುಳುಗಿ ಮೈನವಿರೆದ್ದ ಅರ್ಜುನ\nಭಗವಂತನಿಗೆ ತಲೆಬಾಗಿ ಕೈಜೋಡಿಸಿ ನುಡಿದ.\n\nಭಗವಂತನ ಈ ಅದ್ಭುತ ರೂಪವನ್ನು ಕಂಡ ಅರ್ಜುನ, ಆನಂದ ಆಶ್ಚರ್ಯ ದಿಗ್ಭ್ರಮೆಯಿಂದ\nರೋಮಾಂಚನಗೊಂಡು ನಿಂತ. ಭಗವಂತನ ಅಪೂರ್ವವಾದ ಇಂತಹ ಅದ್ಭುತ ದರ್ಶನ ಸಂಪತ್ತನ್ನು(ಧನ)\nಪಡೆದ ಆತ(ಧನಂಜಯಃ), ಭಕ್ತಿ ಪೂರ್ವಕವಾಗಿ ಉದ್ದಂಡ ನಮಸ್ಕಾರ ಮಾಡಿ, ತನ್ನೆರಡು ಕೈ ಜೋಡಿಸಿ\n(ಕೈಮುಗಿದು) ನಿಂತು, ಭಗವಂತನನ್ನು ಸ್ತೋತ್ರ ಮಾಡಲಾರಂಭಿಸಿದ.",
  "11.15": "ಅರ್ಜುನಃ ಉವಾಚ-ಅರ್ಜುನ ನುಡಿದನು:\n\nಪಶ್ಯಾಮಿ ದೇವಾನ್‌ ತವ ದೇವ ದೇಹೇ ಸರ್ವಾನ್‌ ತಥಾ ಭೂತ ವಿಶೇಷ ಸಂಘಾನ್‌ ।\n\nಬ್ರಹ್ಮಾಣಮ್‌ ಈಶಮ್‌ ಕಮಲಾಸನಸ್ಥಂ ಋಷೀನ್ ಚ ಸರ್ವಾನ್‌ ಉರಗಾನ್‌ ಚ ದಿವ್ಯಾನ್‌ -ಓ ದೇವಾ, ನಿನ್ನ\nಮೈಯಲ್ಲಿ ಕಾಣುತ್ತಿದ್ದೇನೆ ದೇವತೆಗಳನ್ನೆಲ್ಲ. ಅಂತೆಯೇ ಬಗೆಬಗೆಯ ಜೀವಿಗಳ ಗಡಣಗಳನ್ನು ಬ್ರಹ್ಮನನ್ನು ಸ;\nಅವನ ತೊಡೆಯಲ್ಲಿ ಕುಳಿತ ಶಿವನನ್ನು, ಎಲ್ಲಾ ಖುಷಿಗಳನ್ನು ಮತ್ತು ದಿವ್ಯ ಶಕ್ತಿಯ ಉರಗಗಳನ್ನು.\n\nಅರ್ಜುನ ಕೃಷ್ಣನ ಅತ್ಯದ್ಭುತ ರೂಪವನ್ನು ನೋಡುತ್ತಿದ್ದಾನೆ. ಆತನಿಗೆ ಸಮಸ್ತ ದೇವತೆಗಳೂ ಆ\nಭಗವಂತನೊಳಗೆ ಕಾಣುತ್ತಿದ್ದಾರೆ. ದೇವತೆಗಳು, ರಾಕ್ಷಸರು, ಅಸುರರು, ಗಂಧರ್ವರು, ಅಪ್ಸರರು, ಯಕ್ಷರು ,\nಮನುಷ್ಯರು, ಪ್ರಾಣಿಗಳು ಹೀಗೆ ಎಲ್ಲರೂ. ಮುಖ್ಯವಾಗಿ ಅರ್ಜುನ ಭಗವಂತನೊಳಗೆ ಚತುರ್ಮುಖ ಬ್ರಹ್ಮ ಶಿವ,\n\nಮಹಾನ್‌ ಖುಷಿಗಳು ಮತ್ತು ದೇವಾಂಶ ಸಂಭೂತ ದಿವ್ಯ ಉರಗಗಳನ್ನು ಆ ಶೇಷಶಾಯಿ ಭಗವಂತನಲ್ಲಿ\n\nಕಾಣುತ್ತಿದ್ದಾನೆ.",
  "11.16": "ಅನೇಕ ಬಾಹು ಉದರ ವಕ್ರ ನೇತ್ರಮ್‌ ಪಶ್ಯಾಮಿ ತ್ವಾಮ್‌ ಸರ್ವತಃ ಅನಂತ ರೂಪಮ್‌ |\n\nನ ಅಂತಮ್‌ ನ ಮಧ್ಯಮ್‌ ನ ಪುನಃ ತವ ಆದಿಮ್‌ ಪಶ್ಯಾಮಿ ವಿಶ್ವೇಶ್ವರ ವಿಶ್ವರೂಪ - ಎಣಿಕೆಯಿರದ\nತೋಳುಗಳು, ಒಡಲು, ಬಾಯಿ, ಕಣ್ಣುಗಳು. ಎಲ್ಲೆಡೆಯೂ ಎಣಿಕೆಯಿರದ ರೂಪಗಳ ನಿನ್ನನ್ನು ಕಾಣುತ್ತಿದ್ದೇನೆ. ಓ\nಪೊಡವಿಗೊಡೆಯನೇ, ಓ ವಿಶ್ವರೂಪನೇ, ನಿನ್ನ ತುದಿ ಕಾಣುತ್ತಿಲ್ಲ; ಇಲ್ಲ ನಡು; ಇಲ್ಲ ಬುಡ ಕೂಡಾ.",
  "11.17": "ಕಿರೀಟಿನಮ್‌ ಗದಿನಮ್‌ ಚಕ್ರಿಣಮ್‌ ಚ ತೇಜೋರಾಶಿಮ್‌ ಸರ್ವತಃ ದೀಪ್ತಿಮಂತಮ್‌ |\n\nಪಶ್ಯಾಮಿ ತ್ವಾಮ್‌ ದುರ್ನಿರೀಕ್ಷ್ಯಮ್‌ ಸಮಂತಾತ್‌ ದೀಪ್ತ ಅನಳ ಅರ್ಕ ದ್ಯುತಿಮ್‌ ಅಪ್ರಮೇಯಮ್‌-ತಲೆಯಲ್ಲಿ\nಮುಕುಟ. ಕೈಯಲ್ಲಿ ಗದೆ ಮತ್ತು ಚಕ್ರ. ಬೆಳಕಿನ ಮುದ್ದೆಯಾಗಿ ಎಲ್ಲೆಡೆಯೂ ಕೋರಯಿಸುವ ರೂಪ. ಸುಡುವ\nಬೆಂಕಿಯಂತೆ, ಸೂರ್ಯನಂತೆ ಪ್ರಕಾಶವುಳ್ಳ , ಅಳೆಯಲಾಗದ ರೂಪ. ಕಣ್ಕುಕ್ಕುವ ನಿನ್ನ ಆ ರೂಪವನ್ನೇ ಸುತ್ತಲೂ\nಕಾಣುತ್ತಿದ್ದೇನೆ.\n\nಸರ್ವಾಭರಣಭೂಶಿತನಾದ ಮನಮೋಹಕ ರೂಪ ಒಂದು ಕಡೆಯಾದರೆ, ಚಕ್ರ-ಗದೆಯನ್ನು ಹಿಡಿದ ಶತ್ರು\nಭಯಂಕರ ರೂಪ ಇನ್ನೊಂದೆಡೆ. ಹೀಗೆ ಎಲ್ಲವೂ ಒಂದು ಬೆಳಕಿನ ಪುಂಜದಂತೆ ಕಾಣುತ್ತಿದೆ. ನೋಡಲಾಗದ್ದನ್ನು\nಸ್ಪಷ್ಟವಾಗಿ ನೋಡುತ್ತಿರುವ ಅನುಭವ. ಅದು ಸುಡುವ ಬೆಂಕಿಯೋ ಅಥವಾ ಹೊಳೆವ ಸೂರ್ಯನೋ\nತಿಳಿಯುತ್ತಿಲ್ಲ. ಅದೊಂದು ಅಳೆಯಲಾಗದ, ಅರಿಯಲಾಗದ ಅತ್ಯದ್ಳು ತ ಅಪೂರ್ವ ರೂಪ.\n",
  "11.18": "ತ್ವಮ್‌ ಅಕ್ಷರಮ್‌ ಪರಮಮ್‌ ವೇದಿತವ್ಯಮ್‌ ತ್ವಮ್‌ ಅಸ್ಯ ವಿಶ್ವಸ್ಯ ಪರಮ್‌ ನಿಧಾನಮ್‌ |\n\nತ್ವಮ್‌ ಅವ್ಯಯಃ ಶಾಶ್ವತ ಧರ್ಮಗೋಪ್ತಾ ಸನಾತನಃ ತ್ವಮ್‌ ಪುರುಷಃ ಮತಃ ಮೇ - ನೀನು ಅಳಿವಿರದವನು.\nಅರಿಯಬೇಕಾದ ಹಿರಿಯ ತತ್ವ. ನೀನು ಈ ಜಗಕೆಲ್ಲಾ ಹಿರಿಯಾಸರೆ. ನೀನು ಬದಲಾಗದವನು.\nಸನಾತನಧರ್ಮವನ್ನು ಸಲಹುವವನು. ನೀನು ಪುರಾಣ ಪುರುಷೋತ್ತಮ ಎಂದು ಗೊತ್ತು ನನಗೆ.\n\n“ನೀನು ಅಕ್ಷರಂ ಪರಮಂ” ಎನ್ನುತ್ತಾನೆ ಅರ್ಜುನ. ಇಲ್ಲಿ ಅಕ್ಷರ ಎಂದರೆ ಸರ್ವ ವ್ಯಾಪ್ತ, ನಾಶವಿಲ್ಲದ ತತ್ವ,\nಸರ್ವಾಭೀಷ್ಟಪ್ರದ, ಸರ್ವಶಬ್ದವಾಚ್ಯ ಇತ್ಯಾದಿ. ನಾವು ತಿಳಿದುಕೊಳ್ಳಬೇಕಾಗಿರುವುದರಲ್ಲೇ ಸರ್ವಶ್ರೇಷ್ಠವಾದದ್ದು-\nಭಗವಂತ. ಅರ್ಜುನ ಹೇಳುತ್ತಾನೆ: “ನೀನು ಇಡೀ ಜಗತ್ತಿನ ಸೃಷ್ಟಾರ, ಆಶ್ರಯದಾತ. ಸಮಸ್ತ ಜಗತ್ತಿನ\nಮೂಲಾಶ್ರಯ. ಅನಾಧಿ ಅನಂತ ಕಾಲದಲ್ಲಿ ಶಾಶ್ವತ ಧರ್ಮವನ್ನು ರಕ್ಷಣೆ ಮಾಡುವವನು ನೀನು. ಸಮಸ್ತ ವೇದ\nಪ್ರತಿಪಾದ್ಯ ನೀನು ಎನ್ನುವುದು ನನಗೆ ಮನವರಿಕೆಯಾಯಿತು” ಎಂದು. [ಈ ಶ್ಲೋಕದಲ್ಲಿ ಬಂದಿರುವ ಹಲವು\nವಿಶೇಷ ಪದಗಳ(ಅಕ್ಷರಃ, ಪುರುಷಃ, ಅವ್ಯಯಃ, ಶಾಶ್ವತಧರ್ಮ, ಇತ್ಯಾದಿ)ವಿಶೇಷ ಅರ್ಥವನ್ನು ನಾವು ಈ\nಹಿಂದಿನ ಅಧ್ಯಾಯಗಳಲ್ಲಿ ವಿಶ್ಲೇಷಿಸಿರುವುದರಿಂದ ಇಲ್ಲಿ ಆ ವಿವರಣೆಯನ್ನು ಕೊಟ್ಟಿಲ್ಲ].\n",
  "11.19": "ಅನಾದಿ ಮಧ್ಯಾಂತಮ್‌ ಅನಂತವೀರ್ಯಮ್‌ ಅನಂತಬಾಹುಮ್‌ ಶಶಿಸೂರ್ಯನೇತ್ರಮ್‌ ।\n\nಪಶ್ಯಾಮಿ ತ್ವಾಮ್‌ ದೀಪ್ತ ಹುತಾಶ ವಕ್ತ್ರಂ ಸ್ವತೇಜಸಾ ವಿಶ್ವಮ್‌ ಇದಮ್‌ ತಪಂತಮ್‌ -ಗುಣಗಳಿಗೆ ಬುಡವಿಲ್ಲ;\nನಡುವಿಲ್ಲ; ತುದಿಯಿಲ್ಲ. ಆಳವನ್ನು ಅಳೆದವರಿಲ್ಲ. ಎಣಿಕೆಯಿರದ ತೋಳುಗಳು. ಸೂರ್ಯಚಂದ್ರರನು ಹುಟ್ಟಿಸಿದ\nಕಣ್ಣುಗಳು. ಉರಿವ ಬೆಂಕಿಯನುಗುಳುವ ಬಾಯಿ. ಕಾಣುತ್ತಿದ್ದೇನೆ ತನ್ನ ಥಟ್ಟುರಿಯಿಂದ ಈ ಜಗವ ಸುಟ್ಟುರಿವ\n\nನಿನ್ನ ಗುಣಗಳಿಗೆ ಆದಿ ಅಂತ ನಡುವೆಂಬುದಿಲ್ಲ. ನೀನು ಅನಂತವೀರ್ಯ. ಆದಿ ಅಂತವಿಲ್ಲದ ಪರಾಕ್ರಮ ನಿನ್ನದು.\nನಾಶವಿಲ್ಲದ ಅನಂತ ಅವಯವಗಳು. ನಿನ್ನ ಕಣ್ಣುಗಳಿಂದ ಹುಟ್ಟಿದ ಆ ಸೂರ್ಯ ಚಂದ್ರರು; ಉಗುಳುವ ಬೆಂಕಿಯ\nಜ್ವಾಲೆ ನಿನ್ನ ಬಾಯಿಯಲ್ಲಿ. ನಿನ್ನ ತೇಜಸ್ಸಿನಿಂದ ಇಡೀ ವಿಶ್ವ ಸುಟ್ಟುರಿದಂತಿದೆ.\n",
  "11.20": "ದ್ಯಾವಾಪೃಥಿವ್ಯೋಃ ಇದಮ್‌ ಅಂತರಮ್‌ ಹಿ ವ್ಯಾಪ್ತಮ್‌ ತ್ವಯಾ ಏಕೇನ ದಿಶಃ ಚ ಸರ್ವಾಃ ।\n\nದೃಷ್ಟ್ವಾ ಅದ್ಭುತಮ್‌ ರೂಪಮ್‌ ಉಗ್ರಮ್‌ ತವ ಇದಮ್‌ ಲೋಕತ್ರಯಮ್‌ ಪ್ರವ್ಯಥಿತಮ್‌ ಮಹಾತ್ಮನ್‌ -ಈ\nನೆಲ ಮುಗಿಲ ನಡುವೆಲ್ಲಾ ಒಂದೇ ರೂಪದಿಂದ ತುಂಬಿರುವೆ. ನಿನ್ನವೇ ರೂಪಗಳು ಎಲ್ಲಾ ದಿಕ್ಕುಗಳಲ್ಲೂ. ಓ\nಮಹಾತ್ಮನೇ, ಅಚ್ಚರಿಯ, ಎದೆಗೆಡಿಸುವ ನಿನ್ನ ಈ ರೂಪವನ್ನು ಕಂಡು ಕಂಗೆಟ್ಟಿದೆ ಮೂರು ಲೋಕ.\n\nನಿನ್ನ ರೂಪ ಭೂಮಿ ಆಕಾಶವನ್ನು ವ್ಯಾಪಿಸಿ ನಿಂತಿದೆ. ಎಲ್ಲಾ ದಿಕ್ಕುಗಳಲ್ಲಿ ಅನಂತವಾಗಿ ವ್ಯಾಪಿಸಿರುವ ನಿನ್ನ\nರೂಪವನ್ನು ಕಾಣುತ್ತಿದ್ದೇನೆ. ಮೂರು ಲೋಕದಲ್ಲಿ ನಿನ್ನ ರೂಪವನ್ನು ಕಂಡವರು ಈ ನಿನ್ನ ಉಗ್ರ ರೂಪವನ್ನು\nನೋಡಿ ಕಂಗೆಡುತ್ತಿದ್ದಾರೆ. ಜಗತ್ತು ತತ್ತರಿಸುತ್ತಿದೆ. ಎಂದು ದಿಗ್ಭಮೆಯಿಂದ ಅರ್ಜುನ ತನ್ನ ಅನುಭವವನ್ನು\nಭಗವಂತನಲ್ಲಿ ಹೇಳಿಕೊಳ್ಳುತ್ತಾನೆ.\n",
  "11.21": "ಅಮೀ ಹಿ ತ್ವಾಮ್‌ ಸುರಸಂಘಾ ವಿಶಂತಿ ಕೇಚಿತ್‌ ಭೀತಾಃ ಪ್ರಾಂಜಲಯಃ ಗೃಣಂತಿ |\n\nಸ್ವಸ್ತಿ ಇತಿ ಉಕ್ತ್ರಾ ಮಹರ್ಷಿ ಸಿದ್ಧಸಂಘಾಃ ಸ್ತುವಂತಿ ತ್ವಾಮ್‌ ಸ್ತುತಿಭಿಃ ಪುಷ್ಕಳಾಭಿಃ -ನಿನ್ನೊಳಹೋಗುತ್ತಿದ್ದಾರೆ\nಈ ದೇವತೆಗಳು ಗುಂಪುಗೂಡಿ. ಬೆಚ್ಚಿ ಕೈಮುಗಿದು ಬೇಡುತ್ತಿದ್ದಾರೆ. ಮತ್ತೆ ಕೆಲವರು 'ಒಳಿತಾಗಲಿ' ಎಂದು\nಹಾರೈಸುತ್ತಾ ಹತ್ತು ಹಲವು ಹಾಡುಗಬ್ಬಗಳಿಂದ ನಿನ್ನನ್ನು ಹೊಗಳುತ್ತಿದ್ದಾರೆ ಹಿರಿಯ ಖುಷಿಗಳು, ಗುಂಪು\n\nಗುಂಪಾಗಿ.\n\nಕೆಲವರು ನಿನ್ನೊಳಗೆ ಹೋಗುತ್ತಿದ್ದಾರೆ, ಇನ್ನು ಕೆಲವರು ಹೊರಬರುತ್ತಿದ್ದಾರೆ. ಕೆಲವರು ಕೈಮುಗಿದು ನಿನ್ನ ಸ್ತೋತ್ರ\nಮಾಡುತ್ತಿದ್ದಾರೆ. ಜ್ಞಾನಿಗಳು ನಿನ್ನ ಈ ಅದ್ಭುತ ರೂಪವನ್ನು ಕಂಡು “ಜಗತ್ತಿಗೆ ಮಂಗಳವಾಗಲಿ' ಎಂದು\nಹರಸುತ್ತಿದ್ದಾರೆ. ಋಷಿ ಮುನಿಗಳು ನಾನಾ ಸ್ನೋತ್ರಗಳಿಂದ ನಿನ್ನನ್ನು ಸ್ತುತಿಸುತ್ತಿದ್ದಾರೆ.\n",
  "11.22": "ರುದ್ರ ಆದಿತ್ಯಾಃ ವಸವಃ ಯೇಚ ಸಾಧ್ಯಾಃ ವಿಶ್ವೇ ಅಶ್ವಿನೌ ಮರುತಃ ಚ ಉಷ್ಕಪಾಃ ಚ।\n\nಗಂಧರ್ವ ಯಕ್ಷ ಅಸುರ ಸಿದ್ಧ ಸಂಘಾಃ ವೀಕ್ಷಂತೇ ತ್ವಾಮ್‌ ವಿಸ್ಮಿತಾಃ ಚ ಏವ ಸರ್ವೇ -ರುದ್ರರು, ಆದಿತ್ಯರು,\nವಸುಗಳು, ಸಾಧ್ಯರು, ವಿಶ್ವೇದೇವತೆಗಳು, ಅಶ್ವಿಗಳು, ಮರುತ್ತುಗಳು, ಪಿತೃಗಳು, ಗಂಧರ್ವರು, ಯಕ್ಷರು,\nಅಸುರರು, ಸಿದ್ಧರು,-ಇವರೆಲ್ಲಾ ಗುಂಪುಗೂಡಿ ನಿಬ್ಬೆರಗಾಗಿ ನೋಡುತ್ತಿದ್ದಾರೆ ನಿನ್ನನ್ನು.\n\nಏಕಾದಶರುದ್ರರು, ದ್ವಾದಶಾದಿತ್ಯರು, ಅಷ್ಟವಸುಗಳು, ಸಾಧ್ಯರು, ವಿಶ್ವೇದೇವತೆಗಳು, ಅಶ್ವಿಗಳು,\nಮರುತ್ತುಗಳು, ಪಿತೃಗಳು, ಗಂಧರ್ವರು, ದೇವಗಣ ಪ್ರವಿಷ್ಟರಾದ ಯಕ್ಷರು, ಅಸುರರು, ಸಿದ್ಧರು,-ಇವರೆಲ್ಲರೂ\nನಿಬ್ಬೆರಗಾಗಿ ನಿನ್ನನ್ನು ನೋಡುತ್ತಿದ್ದಾರೆ ಎನ್ನುತ್ತಾನೆ ಅರ್ಜುನ.",
  "11.23": "ರೂಪಮ್‌ ಮಹತ್‌ ತೇ ಬಹು ವಕ್ರ ನೇತ್ರಮ್‌ ಮಹಾಬಾಹೋ ಬಹುಬಾಹು ಊರು ಪಾದಮ್‌ ।\n\nಬಹು ಉದರಮ್‌ ಬಹುದಂಷ್ಟ್ರಾ ಕರಾಳಮ್‌ ದೃಷ್ಟ್ವಾ ಲೋಕಾಃ ಪ್ರವ್ಯಥಿತಾಃ ತಥಾ ಅಹಮ್‌ - ಓ ಮಹಾಬಾಹೂ,\nಹಬ್ಬಿ ನಿಂತ ನಿನ್ನ ರೂಪಕ್ಕೆ ಹಲವು ಬಾಯಿ ಕಣ್ಣುಗಳು. ಹಲವು ತೊಡೆ ಕಾಲುಗಳು, ಹಲವು ಹೊಟ್ಟೆಗಳು. ಹಲವು\nದಾಡೆಗಳಿಂದ ಅಬ್ಬರಗೊಂಡ ಈ ರೂಪವನ್ನು ಕಂಡು ಲೋಕದ ಮಂದಿ ಬೆಚ್ಚಿಬಿದ್ದಿದ್ದಾರೆ; ನಾನು ಕೂಡಾ.\n\nಭಗವಂತನ ಅಂಗಾಂಗಗಳಲ್ಲಿ ಹೇಗೆ ಸೃಷ್ಟಿ ಕ್ರಿಯೆ ನಡೆಯುತ್ತಿದೆ ಎನ್ನುವುದನ್ನು ಅರ್ಜುನ ಕಾಣುತ್ತಿದ್ದಾನೆ. ಪುರುಷ\nಸೂಕ್ತದಲ್ಲಿ ಹೇಳುವಂತೆ :\n\nಬ್ರಾಹ್ಮಣೋಸ್ಯ ಮುಖಮಾಸೀತ್‌ | ಬಾಹೂ ರಾಜನ್ಯಃ ಕೃತಃ |\n\nಊರೂ ತದಸ್ಯ ಯದ್ವೈಶ್ಯಃ | ಪದ್ಭ್ಯಾಗ್‌ಂ ಶೂದ್ರೋ ಅಜಾಯತ ॥೧೩॥\nಅಂದರೆ ಭಗವಂತನ ಮುಖದಿಂದ ಜ್ಞಾನಿಗಳ(Wisdom) ಸೃಷ್ಟಿ, ಬಾಹುವಿನಿಂದ ಕ್ಷತ್ರಿಯರ(Protection) ಸೃಷ್ಟಿ,\nಸೊಂಟ ಅಥವಾ ತೊಡೆಯಿಂದ ವೈ ಶ್ಯರ(Production) ಸೃಷ್ಟಿ ಮತ್ತು ಪವಿತ್ರವಾದ ಪಾದದಿಂದ\nಶೂದ್ರರ(Service) ಸೃಷ್ಟಿ. ಈ ನಾಲ್ಕು ವರ್ಗ ಈ ಸಮಾಜದ ನಾಲ್ಕು ಆಧಾರ ಸ್ಥಂಭಗಳು. ಅರ್ಜುನನಿಗೆ ಈ\nನಾಲ್ಕು ವರ್ಗದ ಸೃಷ್ಟಿ ಭಗವಂತನ ದೇಹದಲ್ಲಾಗುತ್ತಿರುವುದು ಕಾಣಿಸುತ್ತಿದೆ. ಅದರ ಜೊತೆಗೆ ಆತ ಅಲ್ಲಿ\nಎಲ್ಲರನ್ನು ಕಬಳಿಸುವ (ಸಂಹಾರ ಕ್ರಿಯೆ) ಹಲವು ದಾಡೆಗಳಿಂದ ತುಂಬಿದ ರೂಪವನ್ನು ಕಾಣುತ್ತಾನೆ. ಭಗವಂತನ\nಈ ರೂಪವನ್ನು ಕಂಡು ಎಲ್ಲರೂ ವಿಸ್ಮಯರಾಗಿದ್ದಾರೆ. “ನಾನೂ ಕೂಡಾ ಗಾಬರಿಗೊಳಗಾಗಿದ್ದೇನೆ” ಎನ್ನುತ್ತಾನೆ\nಅರ್ಜುನ.\n",
  "11.24": "ನಭಃಸ್ಟೃಶಮ್‌ ದೀಪ್ತಮ್‌ ಅನೇಕ ವರ್ಣಮ್‌ ವ್ಯಾತ್ರ ಆನನಮ್‌ ದೀಪ್ತ ವಿಶಾಲ ನೇತ್ರಮ್‌ |\n\nದೃಷ್ಟ್ವಾ ಹಿ ತ್ವಾಂ ಪ್ರವ್ಯಥಿತ ಅಂತರಾತ್ಮಾಃ ಧೃತಿಮ್‌ ನ ವಿಂದಾಮಿ ಶಮಮ್‌ ಚ ವಿಷ್ಣೋ - ಮುಗಿಲ ಮುತ್ತಿಟ್ಟ,\nಹೊಳೆವ ಬಗೆಬಗೆಯ ಬಣ್ಣಗಳು. ತೆರೆದ ಬಾಯಿಗಳು. ಹೊಳೆವಗಲ ಕಣ್ಣುಗಳು. ಇಂತಹ ನಿನ್ನನ್ನು ಕಂಡು ಬಗೆ\nಬೆಚ್ಚಿಬಿದ್ದಿದೆ. ಓಟ ಒಳಗೂ ಹೊರಗೂ ತುಂಬಿ ನಿಂತವನೇ, ನಾನು ಸೈರಿಸಲಾರೆ. ನಾನು ನೆಮ್ಮದಿಗಾಣೆ.\n\nಭೂಮಿ ಆಕಾಶದಲ್ಲಿ ವ್ಯಾಪಿಸಿರುವ ನಿನ್ನ ಅನಂತ ರೂಪ-ಕತ್ತಲೆಯ ಸ್ಪರ್ಶವೇ ಇಲ್ಲದ ಬೆಳಕಿನ ಪುಂಜ. ನಿನ್ನೊಳಗೆ\nಅನೇಕರು ಅನೇಕ ಶ್ರುತಿ ವಚನಗಳಿಂದ, ವೇದಗಳಿಂದ ನಿನ್ನನ್ನು ವರ್ಣಿಸುತ್ತಿದ್ದಾರೆ. ನಿನ್ನ ಅಪ್ರಾಕೃತವಾದ\nಬಣ್ಣವನ್ನು ನಾನು ಕಾಣುತ್ತಿದ್ದೇನೆ. ನಿನ್ನ ಅನುಗ್ರಹ ಬೀರುವ, ಕಾರುಣ್ಯದ ಅರಳುಗಣ್ಣುಗಳನ್ನು ನಾನು ಕಂಡೆ.\nಎಲ್ಲವನ್ನೂ ನೋಡಿ ಮನಸ್ಸು ಗೊಂದಲವಾಗುತ್ತಿದೆ. “ಓ ವಿಷ್ಣೋ, ಈ ನಿನ್ನ ವಿಚಿತ್ರ ರೂಪವನ್ನು ಅರ್ಥ\nಮಾಡಿಕೊಳ್ಳಲಾಗುತ್ತಿಲ್ಲ” ಎನ್ನುತ್ತಾನೆ ಅರ್ಜುನ. [ವಿಷ್ಣು ಅನ್ನುವ ಪದದ ವಿಶಿಷ್ಟವಾದ ಅರ್ಥವನ್ನು ನಾವು ಹಿಂದಿನ\nಅಧ್ಯಾಯದಲ್ಲಿ ವಿಶ್ಲೇಸಿದ್ದೇವೆ]",
  "11.25": "ದಂಷ್ಟ್ರಾ ಕರಾಳಮ್‌ ದೃಷ್ಟ್ವಾ ಲೋಕಾಃ ಪ್ರವ್ಯಥಿತಾಃ ತಥಾ ಅಹಮ್‌ - ಓ ಮಹಾಬಾಹೂ,\nಹಬ್ಬಿ ನಿಂತ ನಿನ್ನ ರೂಪಕ್ಕೆ ಹಲವು ಬಾಯಿ ಕಣ್ಣುಗಳು. ಹಲವು ತೊಡೆ ಕಾಲುಗಳು, ಹಲವು ಹೊಟ್ಟೆಗಳು. ಹಲವು\nದಾಡೆಗಳಿಂದ ಅಬ್ಬರಗೊಂಡ ಈ ರೂಪವನ್ನು ಕಂಡು ಲೋಕದ ಮಂದಿ ಬೆಚ್ಚಿಬಿದ್ದಿದ್ದಾರೆ; ನಾನು ಕೂಡಾ.\n\nಭಗವಂತನ ಅಂಗಾಂಗಗಳಲ್ಲಿ ಹೇಗೆ ಸೃಷ್ಟಿ ಕ್ರಿಯೆ ನಡೆಯುತ್ತಿದೆ ಎನ್ನುವುದನ್ನು ಅರ್ಜುನ ಕಾಣುತ್ತಿದ್ದಾನೆ. ಪುರುಷ\nಸೂಕ್ತದಲ್ಲಿ ಹೇಳುವಂತೆ :\n\nಬ್ರಾಹ್ಮಣೋಸ್ಯ ಮುಖಮಾಸೀತ್‌ | ಬಾಹೂ ರಾಜನ್ಯಃ ಕೃತಃ |\n\nಊರೂ ತದಸ್ಯ ಯದ್ವೈಶ್ಯಃ | ಪದ್ಭ್ಯಾಗ್‌ಂ ಶೂದ್ರೋ ಅಜಾಯತ ॥೧೩॥\nಅಂದರೆ ಭಗವಂತನ ಮುಖದಿಂದ ಜ್ಞಾನಿಗಳ(Wisdom) ಸೃಷ್ಟಿ, ಬಾಹುವಿನಿಂದ ಕ್ಷತ್ರಿಯರ(Protection) ಸೃಷ್ಟಿ,\nಸೊಂಟ ಅಥವಾ ತೊಡೆಯಿಂದ ವೈ ಶ್ಯರ(Production) ಸೃಷ್ಟಿ ಮತ್ತು ಪವಿತ್ರವಾದ ಪಾದದಿಂದ\nಶೂದ್ರರ(Service) ಸೃಷ್ಟಿ. ಈ ನಾಲ್ಕು ವರ್ಗ ಈ ಸಮಾಜದ ನಾಲ್ಕು ಆಧಾರ ಸ್ಥಂಭಗಳು. ಅರ್ಜುನನಿಗೆ ಈ\nನಾಲ್ಕು ವರ್ಗದ ಸೃಷ್ಟಿ ಭಗವಂತನ ದೇಹದಲ್ಲಾಗುತ್ತಿರುವುದು ಕಾಣಿಸುತ್ತಿದೆ. ಅದರ ಜೊತೆಗೆ ಆತ ಅಲ್ಲಿ\nಎಲ್ಲರನ್ನು ಕಬಳಿಸುವ (ಸಂಹಾರ ಕ್ರಿಯೆ) ಹಲವು ದಾಡೆಗಳಿಂದ ತುಂಬಿದ ರೂಪವನ್ನು ಕಾಣುತ್ತಾನೆ. ಭಗವಂತನ\nಈ ರೂಪವನ್ನು ಕಂಡು ಎಲ್ಲರೂ ವಿಸ್ಮಯರಾಗಿದ್ದಾರೆ. “ನಾನೂ ಕೂಡಾ ಗಾಬರಿಗೊಳಗಾಗಿದ್ದೇನೆ” ಎನ್ನುತ್ತಾನೆ\nಅರ್ಜುನ.",
  "11.26": "ಅಮೀ ಚ ತ್ವಾಂ ಧೃತರಾಷ್ಟ್ರಸ್ಯ ಪುತ್ರಾಃ ಸರ್ವೇ ಸಹೈವಾವನಿಪಾಲಸಂಘೈಃ ।\nಭೀಷ್ಮೋ ದ್ರೋಣಃ ಸೂತಪುತ್ರಸ್ತಥಾಸೌ ಸಹಾಸ್ಮದೀಯೈರಪಿ ಯೋಧಮುಖ್ಯೈಃ ॥\n\nಧೃತರಾಷ್ಟ್ರನ ಪುತ್ರರೆಲ್ಲರೂ ತಂತಮ್ಮ ರಾಜಸಮೂಹಗಳೊಂದಿಗೆ ನಿನ್ನ ಮುಖವನ್ನು ಪ್ರವೇಶಿಸುತ್ತಿದ್ದಾರೆ.\n\nಭೀಷ್ಮ, ದ್ರೋಣ, ಕರ್ಣ ಮತ್ತು ನಮ್ಮ ಕಡೆಯ ಮುಖ್ಯ ಯೋಧರೂ ಸಹ ಪ್ರವೇಶಿಸುತ್ತಿದ್ದಾರೆ. ಕಾಲವು ನಿರಪೇಕ್ಷವಾದದ್ದು — ಇಲ್ಲಿ ಕುಲಭೇದವಾಗಲಿ, ಪಕ್ಷಭೇದವಾಗಲಿ ಇಲ್ಲ. ಕಾಲಪುರುಷನಾದ ಭಗವಂತನು ಎಲ್ಲರನ್ನೂ ಸಮಾನ ಭಾವದಿಂದಲೇ ಸ್ವೀಕರಿಸುತ್ತಾನೆ.",
  "11.27": "ಅಮೀ ಚತ್ವಾಂ ಧೃತರಾಷ್ಟ್ರ ಸ್ಯ ಪುತ್ರಾಃ ಸರ್ವೇ ಸಹ ಏವ ಅವನಿಪಾಲ ಸಂಘ್ಯೈಃ |\n\nಭೀಷ್ಮಃ ದ್ರೋಣಃ ಸೂತಪುತ್ರಃ ತಥಾ ಅಸೌ ಸಹ ಅಸ್ಮದೀಯೆ ಹ ಅಪಿ ಯೋಧ ಮುಖ್ಯೇೈಃ ||\n\nವಕ್ರಾಣಿ ತೇ ತ್ವರಮಾಹಾಃ ವಿಶಂತಿ ದಂಷ್ಟ್ರಾ ಕರಾಳಾನಿ ಭಯಾನಕಾನಿ ।\n\nಕೇಚಿತ್‌ ವಿಲಗ್ನಾಃ ದಶನ ಅಂತರೇಷು ಸಂದೃಶ್ಯಂತೇ ಚೂರ್ಣಿತೈಃ ಉತ್ತಮಾಂಗ್ಕೆಃ - ಭೀಷ್ಮ ದ್ರೋಣ ಮತ್ತು\nಕರ್ಣ, ಜೊತೆಗೆ ನಮ್ಮ ಕಾದಾಳುಗಳ ಮುಖಂಡರು ಕೂಡಾ. ಕಾಣುತ್ತಿದ್ದೇನೆ ಕಟವಾಯಿಯೆಡೆಯಲ್ಲಿ ಪಿಕ್ಕು ನುಗ್ಗು\nನುರಿಯಾದ ಕೆಲವರನ್ನು; ನುಜ್ಜುಗುಜ್ಜಾದ ಅವರ ತಲೆಬುರುಡೆಗಳನ್ನು.\n\nಅರ್ಜುನ ಭಗವಂತನಲ್ಲಿ ಭವಿಷತ್ಕಾಲದಲ್ಲಿ ನಡೆಯುವ ಘಟನೆಗಳನ್ನು ಕಾಣುತ್ತಿದ್ದಾನೆ. ಪ್ರಪಂಚದಲ್ಲಿ ಎಲ್ಲವೂ\nಪೂರ್ವ ನಿರ್ಧಾರಿತ. ಇದನ್ನು ಅರ್ಜುನ ತನ್ನ ದಿವ್ಯ ದೃಷ್ಟಿಯಲ್ಲಿ ಕಾಣುತ್ತಿದ್ದಾನೆ ಅಷ್ಟೆ ಭೀಷ್ಮ ದ್ರೋಣ ಮತ್ತು\nಕರ್ಣ ಎಲ್ಲರೂ ಆ ನಿನ್ನ ಬಾಯಿಯೊಳಗೆ ಹೋಗುತ್ತಿದ್ದಾರೆ. ಜೊತೆಗೆ ನಮ್ಮ ಸೈನ್ಯದ ಮುಖಂಡರೂ ಕೂಡಾ. ಅಲ್ಲಿ\nಕೆಲವರು ಭಯಂಕರವಾದ ಆ ನಿನ್ನ ಕೋರೆ ದಾಡೆಗಳಿಗೆ ಸಿಕ್ಕು ನುಜ್ಜುಗುಜ್ಜಾಗುತ್ತಿರುವುದನ್ನು ಕಾಣುತ್ತಿದ್ದೇನೆ.\n",
  "11.28": "ಯಥಾ ನದೀನಾಮ್‌ ಬಹವಃ ಅಂಬುವೇಗಾಃ ಸಮುದ್ರಮ್‌ ಏವ ಅಭಿಮುಖಾಃ ದ್ರವಂತಿ |\n\nತಥಾ ತವ ಅಮೀ ನರಲೋಕವೀರಾಃ ವಿಶಂತಿ ವಕ್ರಾಣಿ ಅಭಿವಿಜ್ವಲಂತಿ --ನರಲೋಕದ ಈ ವೀರರೆಲ್ಲಾ\nಕೋರೈಸುವ ನಿನ್ನ ಮೋರೆಗಳೊಳಗೆ ಸೇರುತ್ತಿದ್ದಾರೆ. ನದಿಗಳ ಹತ್ತು ಹಲವು ನೀರ ಸೆಲೆಗಳು ಕಡಲ ಕಡೆಗೆ\nಹರಿಯುವಂತೆ.\n\nಪುಣ್ಯ ಜೀವಿಗಳು ಭಗವಂತನ ಬಾಯಿಯನ್ನು ಹೇಗೆ ಪ್ರವೇಶಿಸುತ್ತಿದ್ದಾರೆ ಎನ್ನುವುದನ್ನು ಅರ್ಜುನ\nವರ್ಣಿಸುತ್ತಿದ್ದಾನೆ. ಹೇಗೆ ಎಲ್ಲಾ ನದಿ ನೀರು ಸಮುದ್ರವನ್ನು ಸೇರುತ್ತದೋ ಹಾಗೇ ಈ ನರಲೋಕದ ವೀರರು\nನಿನ್ನನ್ನು ಸೇರುತ್ತಿದ್ದಾರೆ ಎನ್ನುತ್ತಾನೆ. ಅರ್ಜುನ. ಇದೊಂದು ಮಾಂಗಲಿಕ ದೃಷ್ಟಾಂತ. ಇಲ್ಲಿ ಭಯಾನಕ\nನೋಟವಿಲ್ಲ.\n",
  "11.29": "ಯಥಾ ಪ್ರದೀಪ್ರಮ್‌ ಜ್ವಲನಮ್‌ ಪತಂಗಾಃ ವಿಶಂತಿ ನಾಶಾಯ ಸಮೃದ್ಧ ವೇಗಾಃ ।\n\nತಥಾ ಏವ ನಾಶಾಯ ವಿಶಂತಿ ಲೋಕಾಃ ತವ ಅಪಿ ವಕ್ರಾಣಿ ಸಮೃದ್ಧ ವೇಗಾಃ --ಲೋಕದ ಮಂದಿಯೆಲ್ಲ\nಗಡಬಡಿಸಿ ಓಡುತ್ತಾ ಬಂದು ಸಾಯಲೆಂದು ನಿನ್ನ ಬಾಯ್ಲ್ಗಳಲ್ಲಿ ಬೀಳುತ್ತಿವೆ- ಪತಂಗಗಳು ಹಾರಿ ಬಂದು\nಬೆಂಕಿಯಲ್ಲಿ ಬಿದ್ದು ಸಾಯುವಂತೆ.\n\nಪಾಪಿಗಳು ಹೇಗೆ ಭಗವಂತನ ಬಾಯಿಯನ್ನು ಪ್ರವೇಶಿಸುತ್ತಿದ್ದಾರೆ ಎಂದು ವರ್ಣಿಸುತ್ತಾ ಅರ್ಜುನ ಹೇಳುತ್ತಾನೆ:\n“ಉರಿಯುವ ಬೆಂಕಿಗೆ ಪತಂಗಗಳು ಬಿದ್ದು ನಾಶವಾದಂತೆ ಗಡಬಡಿಸಿ ಬಂದು ಬಿದ್ದು ನಾಶವಾಗುತ್ತಿದ್ದಾರೆ” ಎಂದು.\n",
  "11.30": "ಲೇಲಿಹ್ಯಸೇ ಗ್ರಸಮಾನಃ ಸಮಂತಾತ್‌ ಲೋಕಾನ್‌ ಸಮಗ್ರಾನ್‌ ವದನೈಃ ಜ್ವಲದ್ಭಿಃ |\n\nತೇಜೋಭಿಃ ಆಪೂರ್ಯ ಜಗತ್‌ ಸಮಗ್ರಮ್‌ ಭಾಸಃ ತವ ಉಗ್ರಾಃ ಪ್ರತಪಂತಿ ವಿಷ್ಣೋ -ಓ ಎಲ್ಲೆಲ್ಲೂ\nತುಂಬಿರುವವನೇ, ಬೆಂಕಿ ಕಾರುವ ಬಾಯಿಗಳಿಂದ ಎಲ್ಲಾ ಲೋಕಗಳನ್ನು ಎಲ್ಲೆಡೆಯೂ ನುಂಗಿ ನೊಣೆಯುತ್ತಿರುವೆ.\nಕೋರೈಸುವ ನಿನ್ನ ಮೈಯ ಹೊಳಪು ಇಡಿಯ ವಿಶ್ವವನ್ನು ರುಳದಿಂದ ತುಂಬಿ ಸುಡುತ್ತಿವೆ.\n\nಎಲ್ಲವನ್ನೂ ನಿನ್ನ ನಾಲಿಗೆಯಿಂದ ಸವರಿ ನುಂಗುತ್ತಿದ್ದೀಯ, ಎಲ್ಲವೂ ನಿನ್ನ ಹೊಟ್ಟೆಯನ್ನು ಸೇರುತ್ತಿವೆ. ಈ ಜಗತ್ತೇ\nನಿನಗೊಂದು ತುತ್ತಾಗುತ್ತಿದೆ. ಆ ನಿನ್ನ ಮೈಯ ತೇಜಸ್ಸು ಜಗತ್ತಿನೆಲ್ದೆಡೆಗೆ ತುಂಬುತ್ತಿದೆ. ಎಲ್ಲರ ಒಳಗೂ ಹೊರಗೂ\nತುಂಬಿರುವ ನೀನು ಸರ್ವ ಸಂಹಾರಕರನಾಗಿ ಕಾಣುತ್ತಿದ್ದೀಯ(ವಿಷ್ಣೋ).\n",
  "11.31": "ಆಖ್ಯಾಹಿ ಮೇ ಕಃ ಭವಾನ್‌ ಉಗ್ರ ರೂಪಃ ನಮಃ ಅಸ್ತು ತೇ ದೇವ ವರ ಪ್ರಸೀದ ।\n\nವಿಜ್ಞಾತುಮ್‌ ಇಚ್ಛಾಮಿ ಭವಂತಮ್‌ ಆದ್ಯಮ್‌ ನ ಹಿ ಪ್ರಜಾನಾಮಿ ತವ ಪ್ರವೃತ್ತಿಮ್‌ -ಹೇಳು ನನಗೆ: ಅಂಜಿಸುವ\nರೂಪ ತಳೆದು ಬಂದ ನಿನ್ನ ಬಿತ್ತರವೇನು? ಓ ಹಿರಿಯ ದೈವತವೇ, ನಿನಗೆ ತಲೆಬಾಗುತಿದ್ದೇನೆ. ದಯೆದೋರು.\nಎಲ್ಲಕ್ಕೂ ಮೊದಲಿರುವ ನಿನ್ನನ್ನು ತಿಳಿಯ ಬಯಸುತ್ತೇನೆ.ನಿನ್ನ ಉದ್ದೇಶವೇನು ಎಂದು ತಿಳಿಯುತ್ತಿಲ್ಲ.\n\nಈ ನಿನ್ನ ಭಯಂಕರ ರೂಪವನ್ನು ಕಂಡು ನನಗೇನೂ ಅರ್ಥವಾಗುತ್ತಿಲ್ಲ. ನಿನ್ನ ಮಹಿಮೆ ಅರಿಯದಾಗಿದ್ದೇನೆ.\nನಿನ್ನಲ್ಲಿ ನಾನು ಶರಣು ಬಂದಿದ್ದೇನೆ. ನನ್ನನ್ನು ಉದ್ಧರಿಸು. ಈ ಭಯಂಕರ ರೂಪ ತೊಟ್ಟ ನಿನ್ನನ್ನು\nತಿಳಿಯಬಯಸುತ್ತಿದ್ದೇನೆ. ಎಂದು ಅರ್ಜುನ ಕೃಷ್ಣನಲ್ಲಿ ಅಂಗಲಾಚಿ ಬೇಡಿಕೊಳ್ಳುತ್ತಾನೆ.\n\nಭಗವಾನುವಾಚ ।\nಕಾಲೋಕ",
  "11.32": "ಭಗವಾನುವಾಚ-ಭಗವಂತ ಹೇಳಿದನು:\n\nಕಾಲಃ ಅಸ್ಮಿ ಲೋಕಕ್ಷಯಕೃತ್‌ ಪ್ರವೃದ್ಧಃ ಲೋಕಾನ್‌ ಸಮಾಹರ್ತುಮ್‌ ಇಹ ಪ್ರವೃತ್ತಃ |\n\nಋತೇ ಅಪಿ ತ್ವಾಮ್‌ ನ ಭವಿಷ್ಯಂತಿ ಸರ್ವೇಯೇ ಅವಸ್ಥಿತಾಃ ಪ್ರತಿ ಅನೀಕೇಷು ಯೋಧಾಃ -ಲೋಕಗಳನ್ನು\nಕಬಳಿಸಲು ಬೆಳೆದು ನಿಂತಿರುವ ಕಾಲ ಪುರುಷ ನಾನು. ಈಗಿಲ್ಲಿ, ಲೋಕಗಳನ್ನು ಮುಗಿಸಿಬಿಡಲೆಂದು\nಹೊರಟವನು. ನೀನಿರದಿದ್ದರೂ (ನಿನ್ನನ್ನು, ನಿನ್ನ ಸೋದರರನ್ನು ಮತ್ತೆ ಕೆಲವರನ್ನು ಬಿಟ್ಟು] ಎರಡೂ ಕಡೆಯ\nಪಡೆಗಳಲ್ಲಿ ನಿಂತ ಯಾವ ಕಾದಾಳುಗಳೂ ಉಳಿಯುವುದಿಲ್ಲ.\n\nಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ನಾನು ಕಾಲಪುರುಷನಾಗಿ ನಿಂತಿದ್ದೇನೆ” ಎಂದು. 'ಕಲ' ಧಾತುವಿನಿಂದ ಬಂದಿರುವ \"ಕಾಲ\nಎನ್ನುವ ಪದ ಅನೇಕ ಅರ್ಥವನ್ನು ಕೊಡುತ್ತದೆ. ಸರ್ವಸಂಹಾರಕ, ಸರ್ವಗುಣಪೂರ್ಣ, ಸರ್ವಜ್ಞ ಇತ್ಯಾದಿ. ಇಲ್ಲಿ\nವಿಶೇಷವಾಗಿ ಕೃಷ್ಣ ಸಂಹಾರ ಶಕ್ತಿಯಾಗಿ ನಿಂತಿದ್ದಾನೆ. ನಾನು ನಿನಗೆ ಸಾರಥಿಯಾಗಿ ನಿಂತು ಭೂಮಿಗೆ\nಭಾರವಾಗಿರುವ ಇವರನ್ನು ಮುಗಿಸಲೆಂದೇ ನಿಂತಿರುವುದು ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಮಹಾಭಾರತ ಯುದ್ಧವನ್ನು\nನೋಡಿದರೆ ಅದು ಒಂದು ಮಹಾಯುದ್ಧ. ಅಲ್ಲಿ ಸುಮಾರು ಐವತ್ತು ಲಕ್ಷ ಮಂದಿ ಸತ್ತಿದ್ದಾರೆ. ಅಂದಿನ ದೇಶದ\nಜನಸಂಖ್ಯೆಯನ್ನು ನೋಡಿದರೆ ಅದು ಒಟ್ಟು ಜನಸಂಖ್ಯೆಯ ಸುಮಾರು ಹತ್ತನೇ ಒಂದು ಭಾಗ. ಭಾಗವತದಲ್ಲಿ\nಹೇಳುವಂತೆ- ಕಾಲಪುರುಷನಾಗಿ ನಿಂತು ಕೃಷ್ಣ ಯಾವುದೇ ಆಯುಧ ಹಿಡಿಯದೇ ಎಲ್ಲರ ಆಯುಸ್ಸನ್ನು ತನ್ನ\nಕಣ್ಣಿನಿಂದ ಹೀರಿದ. ಅದಕ್ಕಾಗಿ ಕೃಷ್ಣ ಅರ್ಜುನನಿಗೆ ಹೇಳುತ್ತಾನೆ. “ನೀನಿಲ್ಲದಿದ್ದರೂ ಇವರೆಲ್ಲರೂ((ಎರಡೂ\nಕಡೆಯವರು) ಸಾಯುತ್ತಾರೆ. ಅವರ ಸಾವು ತೀರ್ಮಾನವಾಗಿ ಬಿಟ್ಟಿದೆ” ಎಂದು.\n",
  "11.33": "ತಸ್ಮಾತ್‌ ತ್ವಮ್‌ ಉತ್ತಿಷ್ಠ ಯಶಃ ಲಭಸ್ವ ಜಿತ್ವಾ ಶತ್ರೂನ್‌ ಭುಂಕ್ಷ್ಯ ರಾಜ್ಯಮ್‌ ಸಮೃದ್ಧಮ್‌ ।\n\nಮಯಾ ಏವ ಏತೇ ನಿಹತಾಃ ಪೂರ್ವಮ್‌ ಏವ ನಿಮಿತ್ತ ಮಾತ್ರಮ್‌ ಭವ ಸವ್ಯಸಾಚಿನ್‌ -ಆದ್ದರಿಂದ ನೀನೆದ್ದು\nನಿಲ್ಲು. ಹಗೆಗಳನ್ನು ಗೆದ್ದು ಹೆಸರು ಗಳಿಸು. ಅರಸೊತ್ತಿಗೆಯ ತುಂಬು ಸಿರಿಯನುಣ್ಣು. ನಾನೇ ಇವರನ್ನು ಈ\nಮೊದಲೇ ಕೊಂಡದಾಗಿದೆ. ಓ ಸವ್ಯಸಾಚಿ(ಎಡದಿಂದಲೂ ಬಾಣ ಪ್ರಯೋಗಿಸಬಲ್ಲ ನಿಪುಣ ಯೋಧ) , ನೀನು\nಬರಿಯ ನೆಪಮಾತ್ರನಾಗು\n\nಅರ್ಜುನನನ್ನು ಕೃಷ್ಣ ಹುರಿದುಂಬಿಸುತ್ತಿದ್ದಾನೆ. ಎದ್ದೇಳು, ಯುದ್ಧಕ್ಕೆ ಸಿದ್ಧನಾಗು. ಈ ಯುದ್ಧದಲ್ಲಿ ನೀನು\nಗೆಲ್ಲುತ್ತೀಯ. ಈ ಶತ್ರುಗಳನ್ನು ಸಂಹಾರ ಮಾಡು. ಏಕೆಂದರೆ ನಾನು ಇವರನ್ನು ಈಗಾಗಲೇ ಕೊಂದಾಗಿದೆ. ಇಲ್ಲಿ\nನೀನು ಕೇವಲ ನಿಮಿತ್ತ ಮಾತ್ರ. ನಿನ್ನ ಪಾಲಿಗೆ ಬಂದ ಕರ್ತವ್ಯವನ್ನು ನಿರ್ವಹಿಸಿ, ನಿನ್ನ ಪಾಲಿನ ಸುಖ\n\nಪ್ರರಾಬ್ಧವನ್ನು ಅನುಭವಿಸು.",
  "11.34": "ದ್ರೋಣಂ ಚ ಭೀಷ್ಮಂ ಚ ಜಯದ್ರಥಂ ಚ ಕರ್ಣಂ ತಥಾ ಅನ್ಯಾನ್‌ ಅಪಿ ಯೋಧ ವೀರಾನ್‌ |।\n\nಮಯಾ ಹತಾನ್‌ ತ್ವಮ್‌ ಜಹಿಮಾ ವ್ಯಥಿಷ್ಠಾಃ ಯುದ್ಧ ಸ್ವ ಜೇತಾ ಅಸಿ ರಣೇ ಸಪತ್ನಾ ನ್‌ - ನಾನೇ ಕೊಂದ\nಇವರನ್ನು ನೀನು ಮುಗಿಸಿಬಿಡು: ದ್ರೋಣನನ್ನು, ಭೀಷ್ಮನನ್ನು, ಜಯದ್ರಥನನ್ನು ಮತ್ತು ಕರ್ಣನನ್ನು; ಹಾಗೆಯೇ\nಬೇರೆ ವೀರ ಹೋರಾಳುಗಳನ್ನು ಕೂಡಾ. ಕಂಗೆಡಬೇಡ, ಹೋರಾಡು. ಕಾಳಗದಲ್ಲಿ ಹಗೆಗಳನ್ನು ಗೆಲ್ಲಲಿರುವೆ.\n\nಇಲ್ಲಿ ನೆರೆದಿರುವ ದ್ರೋಣ, ಭೀಷ್ಮ, ಜಯದ್ರಥ, ಕರ್ಣ, ಇವರೆಲ್ಲರ ಆಯುಸ್ಸ ನ್ನು ನಾನು ಹೀರಿದ್ದೇನೆ. ಆದ್ದರಿಂದ\nನೀನು ಅದಕ್ಕಾಗಿ ದುಃಖಪಡುವ ಅಗತ್ಯವಿಲ್ಲ. ಈ ಜೀವನ ತರಂಗ ಅನಿವಾರ್ಯ. ಇದನ್ನು ಯಾರಿಂದಲೂ\nತಡೆಯಲು ಸಾಧ್ಯವಿಲ್ಲ. ಆದ್ದರಿಂದ ಎದ್ದು ಹೋರಾಡು. ನೀನು ಈ ಧರ್ಮ ಯುದ್ಧದಲ್ಲಿ ಗೆಲ್ಲುವೆ. ನನ್ನ ರಕ್ಷೆಯ\nಪೂರ್ಣ ಪ್ರಸಾದ ನಿನ್ನೊಂದಿಗಿದೆ-ಎಂದು ಕೃಷ್ಣ ಆಶೀರ್ವದಿಸುತ್ತಾನೆ.\n\nಮೊದಲು “ಸೇನಯೋರುಭಯೋರ್ಮಧ್ಯೇ ರಥಂ ಸ್ಥಾಪಯ ಮೇಚ್ಯುತ” ಎಂದು ಅಹಂಕಾರದಿಂದ ಮಾತನಾಡಿದ್ದ\nಅರ್ಜುನ, ನಂತರ ತನ್ನ ಮುಂದೆ ನಿಂತಿರುವ ಹಿರಿಯರನ್ನು ಕಂಡು ಕುಗ್ಗಿ ಯುದ್ಧ ಬೇಡ ಎಂದು ನಿಂತು ಬಿಟ್ಟಿದ್ದ. ಈ\nಎರಡೂ ಸ್ಥಿತಿ ಯಾವುದೇ ವಸ್ತುಸ್ಥಿತಿ ಇಲ್ಲದ ನಿರ್ಧಾರವಾಗಿತ್ತು. ಈ ಕಾರಣಕ್ಕಾಗಿ ಕೃಷ್ಣ ಈ ಹತ್ತು ಅಧ್ಯಾಯಗಳಲ್ಲಿ\nಅರ್ಜುನನಿಗೆ ಉಪದೇಶ ಮಾಡಿ, ಯುದ್ಧ ಎನ್ನುವುದು 'ಧರ್ಮ' ಎನ್ನುವುದನ್ನು ಮನವರಿಕೆ ಮಾಡಿ ಕೊಟ್ಟ. ಈಗ\nತನ್ನ ವಿಶ್ವರೂಪ ದರ್ಶನ ಕೊಟ್ಟು-“ನೀನು ಕೇವಲ ನಿಮಿತ್ತ ಮಾತ್ರ” ಎಂದು ಹೇಳಿದ. ಕೃಷ್ಣನ ಆ ಭಯಂಕರ\nರೂಪ, ಮತ್ತು ಆತನ ಮಾತನ್ನು ಕೇಳಿ ಅರ್ಜುನ ಏನು ಮಾಡಿದ ಎನ್ನುವುದನ್ನು ಸಂಜಯ ಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ\n\nವರ್ಣಿಸುತ್ತಾನೆ:",
  "11.35": "ಕಛ\n\nಸಂಜಯ ಉವಾಚ- ಸಂಜಯ ಹೇಳಿದನು:\n\nಏತತ್‌ ಶ್ರುತ್ವಾ ವಚನಮ್‌ ಕೇಶವಸ್ಯ ಕೃತಾಂಜಲಿ ವೇಪಮಾನಃ ಕಿರೀಟೀ |\n\nನಮಸ್ಕೃತ್ವಾ ಭೂಯಃ ಏವ ಆಹ ಕೃಷ್ಣಮ್‌ ಸ ಗದ್ಗದಮ್‌ ಭೀತಭೀತಃ ಪ್ರಣಮ್ಯ-ಕೃಷ್ಣನ ಈ ಮಾತನ್ನಾಲಿಸಿದ\nಅರ್ಜುನ ಕೈಮುಗಿದು ನಡುಗುತ್ತಾ ಪೊಡಮಟ್ಟು, ಗದ್ಗದಿಸುತ್ತಾ, ಅಳುಕುತ್ತಾ, ಮತ್ತೊಮ್ಮೆ ಮಣಿದು ಮತ್ತೆ ಕೃಷ್ಣನ\nಮುಂದೆ ನುಡಿದನು.\n\nಕೃಷ್ಣನ ಮಾತನ್ನು ಕೇಳಿದ ಅರ್ಜುನ ಭಕ್ತಿಯಿಂದ ಭಗವಂತನಿಗೆ ಕೈ ಮುಗಿದ. ಈ ಸ್ಥಿತಿಯಲ್ಲಿ ಆತ ತತ್ತರಿಸಿ\nನಡುಗುತ್ತಿದ್ದಾನೆ. ತನ್ನ ಸರ್ವಾಂಗದಿಂದ ಭಗವಂತನಿಗೆ ನಮಸ್ಕರಿಸಿ, ಗದ್ಲಿತನಾಗಿ ಮಾತನಾಡಿದ.\n\nಇಲ್ಲಿ ಸಂಜಯ ಭಗವಂತನನ್ನು 'ಕೇಶವ' ಮತ್ತು 'ಕೃಷ್ಣ' ಎಂದು ಸಂಬೋಧಿಸಿದ್ದಾನೆ. ಕೇಶವ ಎಂದರೆ ಜಗತ್ತಿನ\nಸೃಷ್ಟಿ ಮತ್ತು ಸಂಹಾರದ ಮೂಲದಲ್ಲಿರುವ ಶಕ್ತಿಗಳಾದ ಬ್ರಹ್ಮ-ರುದ್ರರನ್ನು ಸೃಷ್ಟಿ-ಸಂಹಾರದಲ್ಲಿ ತೊಡಗಿಸಿ\nನಿಯಂತ್ರಿಸುವವ. ಸಮಸ್ತ ಜೀವಜಾತದೊಳಗಿದ್ದು, ಅವರನ್ನು ನಿಯಂತ್ರಿಸುವ ಸರ್ವಾಂತರ್ಯಾಮಿ ಭಗವಂತ\nಕೇಶವ. ಇನ್ನು 'ಕೃಷ್ಣ' ಎನ್ನುವುದು ಭಗವಂತನ ಮೂಲ ನಾಮ ಕೂಡಾ ಹೌದು. ನಮ್ಮ ಅಹಂಕಾರವನ್ನು,\nಅಜ್ಞಾನವನ್ನು ಕರ್ಷಣೆ ಮಾಡುವ, ಇಡೀ ಲೋಕವನ್ನು ಆಕರ್ಷಣೆ ಮಾಡುವ ಭಗವಂತ, ಸಂಸಾರದಿಂದ\nನಮ್ಮನ್ನು ಕರ್ಷಣೆ ಮಾಡುವ 'ಕೃಷ್ಣ'.",
  "11.36": "ಅರ್ಜುನಃ ಉವಾಚ-ಅರ್ಜುನ ಹೇಳಿದನು:\n\nಸ್ಥಾನೇ ಹೃಷೀಕೇಶ ತವ ಪ್ರಕೀರ್ತ್ಯಾ ಜಗತ್‌ ಪ್ರಹೃಷ್ಯತಿ ಅನುರಜ್ಯತೇ ಚ।\n\nರಕ್ಷಾಂಸಿ ಭೀತಾನಿ ದಿಶಾಃ ದ್ರವಂತಿ ಸರ್ವೇ ನಮಸ್ಯಂತಿ ಚ ಸಿದ್ಧಸಂಘಾಃ -ಇಂದ್ರಿಯಗಳ ದೊರೆಯೇ, ಎಲ್ಲಾ\nಸರಿಯೆ: ಜಗತ್ತು ನಿನ್ನ ಕೊಂಡಾಟದಿಂದ ಹಿಗ್ಗುತ್ತಿದೆ; ಒಲಿಯುತ್ತಿದೆ. ರಕ್ಕಸರು ದಿಕ್ಕೆಟ್ಟು ಓಡುತ್ತಿದ್ದಾರೆ. ಸಿದ್ಧರೆಲ್ಲಾ\nಗುಂಪುಗೂಡಿ ಪೊಡಮಡುತ್ತಿದ್ದಾರೆ.\n\nಈ ಹಿಂದೆ ಹೇಳಿದಂತೆ-ಅರ್ಜುನನಿಗೆ ವಿಶ್ವರೂಪ ದರ್ಶನವಾದಾಗ, ಇಡೀ ವಿಶ್ವದಲ್ಲಿ ಅನೇಕ ಮಂದಿ ಜ್ಞಾನಿಗಳಿಗೆ,\nದೇವತೆಗಳಿಗೆ ಕೂಡಾ ಈ ಅಪರೂಪದ ಭಗವಂತನ ರೂಪ ದರ್ಶನವಾಗಿದೆ. ಅರ್ಜುನ ತನ್ನ ಅಂತರಂಗದಲ್ಲಿ\nತನಗೆ ಕಾಣುತ್ತಿರುವ ವಿಚಾರವನ್ನು ಹೇಳುತ್ತಿದ್ದಾನೆ. ಇಷ್ಟೇ ಅಲ್ಲದೆ ಬಾಹ್ಯ ವಸ್ತುಸ್ಥಿತಿ ಕೂಡಾ ಆತನಿಗೆ\nಭಗವಂತನಲ್ಲಿ ಕಾಣಿಸುತ್ತಿದೆ. ಅದನ್ನು ಅರ್ಜುನ ಇಲ್ಲಿ ವಿವರಿಸುತ್ತಿದ್ದಾನೆ- “ಖುಷಿಗಳು, ಜ್ಞಾನಿಗಳು ನಿನ್ನ\nಗುಣಗಾನ ಮಾಡುತ್ತಿದ್ದಾರೆ. ನಿನ್ನನ್ನು ಕೊಂಡಾಡಿ ರೋಮಾಂಚನಗೊಳ್ಳುತ್ತಿದ್ದಾರೆ. ದುಷ್ಟಶಕ್ತಿಗಳು ನಿನ್ನನ್ನು\nಕಂಡು ಹೆದರಿ ಓಡುತ್ತಿವೆ. ಸಾತ್ವಿಕರು ಸಿದ್ಧರು ಕುಣಿದು ಕುಪ್ಪಳಿಸುತ್ತಿದ್ದಾರೆ. ಇದೆಲ್ಲವೂ ಯುಕ್ತವೇ ಸರಿ.\n",
  "11.37": "ಕಸ್ಮಾತ್‌ ಚ ತೇ ನ ನಮೇರನ್‌ ಮಹಾತ್ಮನ್‌ ಗರೀಯಸೇ ಬ್ರಹ್ಮಣಃ ಅಪಿ ಆದಿಕರ್ತ್ರೇ |\n\nಅನಂತ ದೇವೇಶ ಜಗನ್ನಿವಾಸ ತ್ವಮ್‌ ಅಕ್ಷರಮ್‌ ಸತ್‌ ಅಸತ್‌ ತತ್ಸರಮ್‌ ಯತ್‌ -ಓ ಮಹಾತ್ಮನೇ, ಅವರೇಕೆ\nಪೊಡಮಡದೇ ಇದ್ದಾರು ನಿನಗೆ; ಬ್ರಹ್ಮನಿಗೂ ಹಿರಿಯನಿಗೆ; ಮೊಟ್ಟ ಮೊದಲ ತಂದೆಗೆ. ಓ ಕೊನೆಯಿರದವನೇ,\nಸಗ್ಗಿಗರೊಡೆಯನೇ, ಜಗದ ಆಸರೆಯೇ, ನೀನು ಅಳಿವಿರದವನು. ಕಾಣುವ, ಕಾಣದ ವಿಶ್ವದೊಳಗಿದ್ದು\nಅದರಾಚೆಗಿರುವವನು.\n\nನಿನ್ನ ನ್ನು ತಿಳಿದವರು ನಿನಗೆ ನಮಸ್ಕಾರ ಮಾಡದೇ ಇರಲು ಸಾಧ್ಯವೇ ಇಲ್ಲ. ನೀನು ಪರಿಪೂರ್ಣವಾದ ಆತ್ಮ. ಈ\nಜಗತ್ತಿನ ತಂದೆಯಾದ ಆ ಚತುರ್ಮುಖನಿಗೂ ನೀನು ತಂದೆ. ಇಂತಹ ನಿನಗೆ ನಮಸ್ಕರಿಸದೇ ಇರಲು\nಸಾಧ್ಯವಿಲ್ಲ. ನೀನು ದೇಶ, ಕಾಲ ಮತ್ತು ಗುಣಗಳಿಂದ ಅನಂತ. ನೀನು ಎಲ್ಲರ ಒಳಗೂ ಹೊರಗೂ ತುಂಬಿ\nನಿಂತಿರುವ ಜಗನ್ನಿವಾಸ; ನೀನು ನಿರ್ಧಿಷ್ಟ... ಹಾಗೂ ದೋಷ ರಹಿತ ಜ್ಞಾನಾನಂದಮೂರ್ತಿ(ಸತ್‌).\nಅವ್ಯಕ್ತಮೂರ್ತಿಯಾದ ನಿನ್ನನ್ನು (ಅಸತ್‌) ಹೊರಗಣ್ಣಿನಿಂದ ಕಾಣಲಾರೆವು. ನೀನು ಅಕ್ಷರಃ, ನೀನು ದೇವೇಶ,\nನೀನು ಕಾರಣಗಳಿಗೂ ಕಾರಣ, ನೀನು ಜಗದ ಆಸರೆ.\n",
  "11.38": "ತ್ವಮ್‌ ಆದಿದೇವಃ ಪುರುಷಃ ಪುರಾಣಃ ತ್ವಮ್‌ ಅಸ್ಯ ವಿಶ್ವಸ್ಯ ಪರಮ್‌ ನಿಧಾನಮ್‌ ।\n\nವೇತ್ತಾ ಅಸಿ ವೇದ್ಯಮ್‌ ಚ ಪರಮ್‌ ಚ ಧಾಮ ತ್ವಯಾ ತತಮ್‌ ವಿಶ್ವಮ್‌ ಅನಂತರೂಪ -ನೀನು\nದೇವತೆಗಳಿಗೂ ಮೊದಲಿಗೆ. ಪುರಾಣಪುರುಷ. ನೀನು ಈ ಜಗದ ಹಿರಿಯಾಸರೆ. ಎಲ್ಲವನ್ನೂ ತಿಳಿದವನು. ಎಲ್ಲರೂ\nತಿಳಿಯಬೇಕಾದವನು. ಹಿರಿಯ ಬೆಳಕು. ಓ ಅನಂತರೂಪನೇ, ಇಡಿಯ ವಿಶ್ವ ನಿನ್ನಿಂದ ತುಂಬಿದೆ.\n\nನೀನು. ಆದಿದೇವಃ, ನೀನು ಪುರಾಣಪುರುಷಃ, ಈ ಜಗತ್ತಿನಲ್ಲಿ ಕೊನೆಯಾಸರೆ ನೀನು. ಎಲ್ಲರೂ\nತಿಳಿಯಬೇಕಾದವನು, ಎಲ್ಲವನ್ನೂ ತಿಳಿದ ನೀನು ಎಲ್ಲವನ್ನೂ ಮೀರಿದ ಪರಂಧಾಮ. ಅನಂತರೂಪನಾದ ನೀನು\nಇಡೀ ವಿಶ್ವವನ್ನು ವ್ಯಾಪಿಸಿ ನಿಂತಿದ್ದೀಯ.\n",
  "11.39": "ವಾಯುಃ ಯಮಃ ಅಗ್ನಿಃ ವರುಣಃ ಶಶಾಂಕಃ ಪ್ರಜಾಪತಿಃ ತ್ವಮ್‌ ಪ್ರಪಿತಾಮಹಃ ಚ ।\n\nನಮಃ ನಮಃ ತೇ ಅಸ್ತು ಸಹಸ್ರಕೃತ್ವಃ ಪುನಃ ಚ ಭೂಯಃ ಅಪಿ ನಮಃ ನಮಃ ತೇ -ವಾಯು, ಯಮ, ಅಗ್ನಿ,\nವರುಣ, ಚಂದ್ರ, ಪ್ರಜಾಪತಿ ಎಲ್ಲಾ ನೀನೆ. [ವ-ಬಲರೂಪ, ಆಯಾಇಜ್ಞಾನರೂಪ. ಆದ್ದರಿಂದ \"ವಾಯು'. ಎಲ್ಲವನ್ನು\nನಿಯಮಿಸುವುದರಿಂದ “ಯಮ', ಅಗ-ಚಲನೆ ಇಲ್ಲದ ವಿಶ್ವಕ್ಕೆ, ನಿಂಚಲನೆ ನೀಡುವುದರಿಂದ “ಅಗ್ನಿ”. ಭಕ್ತರನ್ನು\nವರಣ ಮಾಡುವುದರಿಂದ ವರುಣಃ. ಶಶ-ಮಿಗಿಲಾದ ಆನಂದದಿಂದ ಅಂಕ-ಅಂಕಿತನಾದ್ದರಿಂದ “ಶಶಾಂಕ”.\nಪ್ರಜಾ-ಪ್ರಜೆಗಳ, ಪತಿ-ಪಾಲಕನಾದ್ದರಿಂದ “ಪ್ರಜಾಪತಿ'.] ನೀನೇ ಜಗದ ಮುತ್ತಜ್ಜ. ಸಾವಿರಬಾರಿ ನಿನಗೆ\nನಮೋನಮೋ ಎಂದು ಮಣಿವೆ. ಮತ್ತೊಮ್ಮೆ ಮಗದೊಮ್ಮೆ ನಿನಗೆ ವಂದನೆ; ವಂದನೆ.\n\nನೀನು ವಾಯುಃ, ಯಮ, ವರುಣಃ, ಶಶಾಂಕಃ, ಪ್ರಜಾಪತಿಃ, ನೀನು ಜಗದ ಮುತ್ತಜ್ಜ. ನಿನಗೆ ಸಹಸ್ರ ಬಾರಿ\nವಂದನೆ.\n",
  "11.40": "ನಮಃ ಪುರಸ್ತಾತ್‌ ಅಥ ಪೃಷ್ಠತಃ ತೇ ನಮಃ ಅಸ್ತು ತೇ ಸರ್ವತಃ ಏವ ಸರ್ವ |\n\nಅನಂತವೀರ್ಯ ಅಮಿತವಿಕ್ರಮಃ ತ್ವಮ್‌ ಸರ್ವಮ್‌ ಸಮಾಪ್ರೋಷಿ ತತಃ ಅಸಿ ಸರ್ವಃ -ಮುಂಗಡ ನಿನಗೆ\nವಂದನೆ. ಮತ್ತೆ ಬೆಂಗಡೆ ನಿನಗೆ ವಂದನೆ. ಓ, ಎಲ್ದೆಡೆ ಇರುವವನೇ, ಎಲ್ಲಾ ಕಡೆ ನಿನಗೆ ವಂದನೆ. ನೀನು\nಎಲ್ಲೆಯಿರದ ಬೀರದವನು.ಅಳತೆಯಿರದ ಅಳವಿನವನು. ಎಲ್ಲೆಡೆಯೂ ತುಂಬಿರುವೆ. ಅದಕ್ಕೆಂದು ನೀನೇ ಎಲ್ಲಾ.\n\nಭಗವಂತನ ವಿಶ್ವರೂಪದಲ್ಲಿ ಆತನ ಮುಂಭಾಗ ಯಾವುದು ಹಿಂಭಾಗ ಯಾವುದು ಎಂದು ಹೇಗೆ\nಗುರುತಿಸುವುದು. ಇದು ಅಸಾಧ್ಯ. ಅದಕ್ಕಾಗಿ ಅರ್ಜುನ ಹೇಳುತ್ತಾನೆ: ನಿನಗೆ ಎದುರಿನಿಂದ ನಮಸ್ಕಾರ, ನಿನ್ನ\nಬೆಂಭಾಗದಿಂದ ನಮಸ್ಕಾರ, ಎಲ್ದೆಡೆ ತುಂಬಿರುವ ನಿನಗೆ ಎಲ್ಲೆಡೆಯಿಂದ ನಮಸ್ಕಾರ. ನೀನು ಅನಂತವೀರ್ಯಃ.\nನೀನು ಅಮಿತವಿಕ್ರಮಃ. ಓ ಸರ್ವನೇ, ನಿನಗೆ ನಮಸ್ಕಾರ. ಜಗತ್ತಿನ ಸಮಸ್ತಜೀವ ಜಾತದ ಸೃಷ್ಟಿಗೆ ಕಾರಣವಾಗಿ\nಎಲ್ಲೆಡೆ ತುಂಬಿರುವ ಜಗತ್ತಿನ ನಿಯಾಮಕನಾದ ಈ ಅನಂತ ಶಕ್ತಿಗೆ ನಮಸ್ಕಾರ. ಎಲ್ಲವೂ ನೀನೇ.",
  "11.41": "ಸಖೇತಿ ಮತ್ವಾ ಪ್ರಸಭಂ ಯದುಕ್ತಂ ಹೇ ಕೃಷ್ಣ ಹೇ ಯಾದವ ಹೇ ಸಖೇತಿ ।\nಅಜಾನತಾ ಮಹಿಮಾನಂ ತವೇದಂ ಮಯಾ ಪ್ರಮಾದಾತ್ ಪ್ರಣಯೇನ ವಾಪಿ ॥\nಯಚ್ಚಾವಹಾಸಾರ್ಥಮಸತ್ಕೃತೋಸಿ ವಿಹಾರಶಯ್ಯಾಸನಭೋಜನೇಷು ।\nಏಕೋಥವಾಪ್ಯಚ್ಯುತ ತತ್ಸಮಕ್ಷಂ ತತ್ ಕ್ಷಾಮಯೇ ತ್ವಾಮಹಮಪ್ರಮೇಯಮ್ ॥\n\nನಿನ್ನ ಮಾಹಾತ್ಮ್ಯವನ್ನು ಅರಿಯದೆ, ಪ್ರಮಾದದಿಂದಲೋ ಅಥವಾ ಪ್ರೀತಿಯಿಂದಲೋ ನಿನ್ನನ್ನು 'ಕೃಷ್ಣಾ, ಯಾದವನೇ, ಗೆಳೆಯನೇ' ಎಂದು ಗದರಿಸಿ ಕರೆದದ್ದಕ್ಕೆ ಮತ್ತು ಹಾಸ್ಯಕ್ಕಾಗಿ ಕ್ರೀಡೆ, ಶಯ್ಯೆ, ಆಸನ, ಭೋಜನಗಳಲ್ಲಿ ಒಂಟಿಯಾಗಿದ್ದಾಗ ಅಥವಾ ಇತರರ ಎದುರು ನಿನಗೆ ಮಾಡಿದ ಅಪಚಾರಗಳಿಗೆ — ಹೇ ಅಚ್ಯುತ, ಅಪ್ರಮೇಯನೇ, ನಿನ್ನಲ್ಲಿ ಕ್ಷಮೆ ಯಾಚಿಸುತ್ತೇನೆ.\n\nತಂದೆ-ಮಗ, ಗೆಳೆಯ-ಗೆಳೆಯ, ಪ್ರಿಯ-ಪ್ರಿಯೆ — ಈ ಮೂರು ಸಂಬಂಧಗಳನ್ನು ಉಲ್ಲೇಖಿಸಿ ಕ್ಷಮೆಯಾಚನೆ. ಭಗವಂತನೊಂದಿಗೆ ಭಕ್ತನ ಸಂಬಂಧವು ಮೂರು ವಿಧದಲ್ಲಿ ಇರಬಹುದು.",
  "11.42": "ಸಖಾ ಇತಿ ಮತ್ವಾ ಪ್ರಸಭಮ್‌ ಯತ್‌ ಉಕ್ತಮ್‌ ಹೇ ಕೃಷ್ಣ ಹೇಯಾದವ ಹೇ ಸಖೇಇತಿ।\nಅಜಾನತಾ ಮಹಿಮಾನಮ್‌ ತವ ಇದಮ್‌ ಮಯಾ ಪ್ರಮಾದಾತ್‌ ಪ್ರಣಯೇನ ವಾಪಿ ॥\nಯತ್‌ ಚ ಅವಹಾಸ ಅರ್ಥಮ್‌ ಅಸತ್‌ ಕೃತಃ ಅಸಿ ವಿಹಾರ ಶಯ್ಯಾ ಆಸನ ಭೋಜನೇಷು ।\nಏಕಃ ಅಥವಾ ಅಪಿ ಅಚ್ಯುತ ತತ್‌ ಸಮಕ್ಷಮ್‌ ತತ್‌ ಕ್ಷಾಮಯೇ ತ್ವಾಮ್‌ ಅಹಮ್‌ ಅಪ್ರಮೇಯಮ್‌ -ನಿನ್ನ\nಹಿರಿಮೆಯನ್ನು ಅರಿಯದೆ ಗೆಳೆಯನೆಂದು ತಿಳಿದು ದುಡುಕಿ ನುಡಿದದ್ದುಂಟು. ನನ್ನ ಎಡವಿನಿಂದ ಅಥವಾ\nಸಲಿಗೆಯಿಂದ- “ಏ ಕೃಷ್ಣ, ಏ ಗೆಳೆಯ” ಎಂದು ಕರೆದದ್ದುಂಟು. ವಿಹಾರದಲ್ಲಿದ್ದಾಗ, ಮಲಗಿದ್ದಾಗ, ಕೂತಾಗ,\nಊಟಮಾಡುವಾಗ- ಎಲ್ಲಾ ಮಾಡಿಸುವ ನಿನ್ನನ್ನು ಅಣಕಕ್ಕಾಗಿ ಕಡೆಗಣಿಸಿದ್ದುಂಟು. ಆದ್ದರಿಂದ ಓ ಕುಗ್ಗದ\nಎತ್ತರವೇ, ತಿಳಿವಿಗೆಟುಕದ, ಸಾಟಿಯಿರದ ನಿನ್ನೆದುರು ಬೇಡಿಕೊಳ್ಳುತ್ತಿದ್ದೇನೆ-ಅದನ್ನೆಲ್ಲಾ ಮರೆತು ಮನ್ನಿಸುವಂತೆ.\n\nಅರ್ಜುನನಿಗೆ ತಾನು ಹಿಂದೆ ಕೃಷ್ಣನೊಂದಿಗೆ ನಡೆದುಕೊಂಡ ರೀತಿ ಬಗ್ಗೆ ಪಶ್ಚಾತ್ತಾಪವಾಗುತ್ತದೆ. ಕೃಷ್ಣ ಜಗತ್ತಿನ\nಮೂಲಶಕ್ತಿ ಎನ್ನುವ ಕಲ್ಪನೆ ಇಲ್ಲದೆ ತಾನು ನಡೆದುಕೊಂಡ ರೀತಿ ಬಗ್ಗೆ ಆತ ಕೃಷ್ಣನಲ್ಲಿ ಕ್ಷಮೆ ಬೇಡುತ್ತಾನೆ.\nತಿಳಿದೋ ತಿಳಿಯದೆಯೋ, ಬೇಜವಾಬ್ಧಾರಿಯಿಂದಲೋ ಅಥವಾ ಪ್ರೀತಿಯಿಂದಲೋ ಮಾಡಿದ ತಪ್ಪುಗಳನ್ನು\nಕ್ಷಮಿಸು ಎಂದು ಆತ ಭಗವಂತನಲ್ಲಿ ಬೇಡುತ್ತಾನೆ. ಇಲ್ಲಿ ಬಂದಿರುವ “ಏಕ' ಎನ್ನುವ ಪದಕ್ಕೆ ವಿಶೇಷ ಅರ್ಥವಿದೆ.\nಏಕಃ ಎಂದರೆ ಸರ್ವೋತ್ತಮ ಮತ್ತು ಸರ್ವಕರ್ತ(ಏಷ ಏವ ಕರೋತಿ-ಏಕಃ). ಸರ್ವಕರ್ತ-ಸರ್ವೋತ್ತಮನಾದ\nನಿನ್ನನ್ನು ಪರಿಹಾಸ್ಯ ಮಾಡಿ ಸಲುಗೆಯಿಂದ ಮಾತನಾಡಿದೆ, ನೀನು ಅಚ್ಯುತಃ. ನಿನ್ನ ಸಾಮರ್ಥ್ಯ, ಗುಣ, ದೇಹದಲ್ಲಿ\nಚ್ಯುತಿ ಇಲ್ಲ. ಚ್ಯುತವಾದ ನನ್ನ ಬುದ್ಧಿಯಿಂದ ಇದನ್ನು ನಾನು ಗ್ರಹಿಸಲಿಲ್ಲ. ನಾನು ಈ ರೀತಿ\nನೆಡೆದುಕೊಳ್ಳಬಾರದಿತ್ತು. ನಾನು ಮಾಡಿರುವ ಅಪರಾಧಕ್ಕೆ ನಿನ್ನ ಬಳಿ ಕ್ಷಮೆ ಬೇಡುತ್ತಿದ್ದೇನೆ. ನೀನು ಅಪ್ರಮೇಯ-\nಕಾಲ-ದೇಶಗಳಿಂದ ವ್ಯಾಪ್ತನಾದ ನೀನು ನಮ್ಮ ಅರಿವಿಗೆ ಎಟುಕದವನು. ಈಗ ನನಗೆ ನನ್ನ ತಪ್ಪಿನ\n\nಕೆ\nಅರಿವಾಯಿತು. ಅಜ್ಞಾನದಿಂದ ತಪ್ಪು ಮಾಡುತ್ತಿದ್ದೇನೆ ಎನ್ನುವ ತಿಳುವಳಿಕೆ ಬಂತು.\n",
  "11.43": "ಪಿತಾ ಅಸಿ ಲೋಕಸ್ಯ ಚರ ಅಚರಸ್ಯ ತ್ವಮ್‌ ಅಸ್ಯ ಪೂಜ್ಯಃ ಚ ಗುರುಃ ಗರೀಯಾನ್‌ |\n\nನ ತ್ವತ್‌ ಸಮಃ ಅಸ್ತಿ ಅಭ್ಯಧಿಕಃ ಕುತಃ ಅನ್ಯಃ ಲೋಕತ್ರಯೇ ಅಪಿ ಅಪ್ರತಿಮ ಪ್ರಭಾವ -ಈ ಚರಾಚರದ ಜಗದ\nತಂದೆ ನೀನು. ಆರಾಧನೆಯ ಕೇಂದ್ರ. ಗುರುವಿಗೂ ಹಿರಿಯ ಗುರು. ಜೋಡಿಯಿರದ ಹಿರಿಮೆಯೇ, ಮೂರು\nಲೋಕದಲ್ಲೂ ನಿನಗೆ ಸಾಟಿ ಇಲ್ಲ. ಬೇರೆ ಮಿಗಿಲು ಮತ್ತೆಲ್ಲಿ?\n\nಎಲ್ಲರನ್ನೂ ಸೃಷ್ಟಿಸಿದವ, ಎಲ್ಲರನ್ನೂ ಪಾಲಿಸುವ ನೀನು ಜಗದ ತಂದೆ. ಜಗದ ಗುರುವಾದ ನಿನ್ನನ್ನು ನಾನು\nತೀರಾ ಸಲುಗೆಯಿಂದ ಕಂಡೆ. ನಿನಗೆ ಸಾಟಿಯಾದವರು ಇನ್ನೊಬ್ಬರಿಲ್ಲ. ನಿನ್ನನ್ನು ಹೋಲಿಸುವ ಇನ್ನೊಂದು\nದೃಷ್ಟಾಂತವಿಲ್ಲ. ಇಡೀ ಜಗತ್ತಿನಲ್ಲಿ ನಿನ್ನನ್ನು ಮೀರಿಸುವ ಇನ್ನೊಂದು ಶಕ್ತಿ ಇಲ್ಲ. [ಇಲ್ಲಿ ಮೂರು ಲೋಕಗಳು\nಎಂದರೆ ಭೂಮಿಯಿಂದ ಕೆಳಗಿರುವ ಲೋಕಗಳ ಒಂದು ಗುಂಪು, ಭೂಲೋಕ ಮತ್ತು ಭೂಮಿಯಿಂದ ಮೇಲಿರುವ\nಲೋಕಗಳ ಗುಂಪು.] ನೀನು ಎಲ್ಲಾ ಕಾರಣಗಳ ಕಾರಣ. ನಿನಗಿಂತ ಮಿಗಿಲು ಇನ್ನೆಲ್ಲಿ?\n",
  "11.44": "ತಸ್ಮಾತ್‌ ಪ್ರಣಮ್ಯ ಪ್ರಣಿಧಾಯ ಕಾಯಮ್‌ ಪ್ರಸಾದಯೇ ತ್ವಾಮ್‌ ಅಹಮ್‌ ಈಶಮ್‌ ಈಡ್ಯಮ್‌ |\n\nಪಿತಾ ಇವ ಪುತ್ರಸ್ಯ ಸಖಾಇವ ಸಖ್ಯಃ ಪ್ರಿಯಃ ಪ್ರಿಯಾಯಾಃ ಅರ್ಹಸಿ ದೇವ ಸೋಢುಮ್‌ -ಆದ್ದರಿಂದ, ಎಲ್ಲರೂ\nಹೊಗಳುವ, ಎಲ್ಲರ ದೊರೆಯಾದ ನಿನ್ನೆದುರು ಮೈಚೆಲ್ಲಿ, ಕಾಲಿಗೆರಗಿ ಓಲೈಸುತ್ತಿದ್ದೇನೆ: ಓ ದೇವ, ನನ್ನ ಮೆಚ್ಚಿನ\nನೀನು ನಿನ್ನ ಮೆಚ್ಚಿನ ನನಗಾಗಿ ನನ್ನ ತಪ್ಪುಗಳನ್ನು ಮನ್ನಿಸಬೇಕು. ತಂದೆ-ಮಗನ ತಪ್ಪನ್ನು, ಗೆಳೆಯ-ಗೆಳೆಯನ\nತಪ್ಪನ್ನು ಮನ್ನಿಸುವಂತೆ.\n\nನಿನ್ನೆದುರು. ನಿಲ್ಲಲಾಗುತ್ತಿಲ್ಲ. ಮೈಚೆಲ್ಲಿ ಹೊರಳಾಡಬೇಕು ಎನ್ನಿಸುತ್ತಿದೆ. ಎಲ್ಲರಿಂದ ಸ್ತುತನಾದ ನಿನ್ನಲ್ಲಿ\nಬೇಡಿಕೊಳ್ಳುತ್ತಿದ್ದೇನೆ. ಮಗ ಮಾಡಿದ ತಪ್ಪನ್ನು ತಂದೆ ಕ್ಷಮಿಸುವಂತೆ, ಗೆಳೆಯನ ತಪ್ಪನ್ನು ಗೆಳೆಯ\nಕ್ಷಮಿಸುವಂತೆ, ಜಗದ ತಂದೆಯಾದ ನೀನು, ಜಗತ್ತಿನ ಎಲ್ಲರ ಅಂತಃಕರಣದ ಮಿತ್ರನಾದ ನೀನು, ನನ್ನನ್ನು\nಕ್ಷಮಿಸು.\n",
  "11.45": "ಅದೃಷ್ಟ ಪೂರ್ವಮ್‌ ಹೃಷಿತಃ ಅಸ್ಮಿ ದೃಷ್ಟ್ವಾ ಭಯೇನ ಚ ಪ್ರವ್ಯದಿ ತಮ್‌ ಮನಃ ಮೇ।\n\nತತ್‌ ಏವ ಮೇ ದರ್ಶಯ ದೇವ ರೂಪಮ್‌ ಪ್ರಸೀದ ದೇವೇಶ ಜಗನ್ನಿವಾಸ -ಹಿಂದೆಂದೂ ಕಂಡರಿಯದ\nರೂಪವನ್ನು ಕಂಡು ಸಡಗರಪಟ್ಟಿದ್ದೇನೆ; ಕಂಡು ಗಾಬರಿಗೊಂಡು ಬಗೆಗೆಟ್ಟಿದ್ದೇನೆ ಕೂಡಾ. ಓ ಸಗ್ಗಿಗರ ದೊರೆಯೇ,\nಓ ಜಗದ ಆಸರೆಯೇ, ದಯೆದೋರು. ಓ ದೇವ, ನನಗೆ ಅದೇ ರೂಪವನ್ನು ತೋರು.\n\nಎಂದೂ ಕಾಣದ ಈ ನಿನ್ನ ಅದ್ಭು ತ ರೂಪವನ್ನು ಕಂಡು ಖುಷಿ ಪಟ್ಟಿದ್ದೇನೆ. ಆದರೆ ಇಡೀ ಜಗತ್ತನ್ನು ಸಂಹಾರ\nಮಾಡುವ ನಿನ್ನ ಉಗ್ರ ರೂಪವನ್ನು ಕಂಡು ಭಯವಾಗುತ್ತಿದೆ. ಒಂದು ಕಡೆ ಆನಂದ ಮತ್ತು ಇನ್ನೊಂದು ಕಡೆ\nದಿಗಿಲು. ಇದರಿಂದ ನಾನು ಕಂಗಾಲಾಗಿದ್ದೇನೆ. ಅದಕ್ಕಾಗಿ ಆ ನಿನ್ನ ಕೃಷ್ಣ' ರೂಪವನ್ನು ತೋರು.",
  "11.46": "ಕಿರೀಟಿನಮ್‌ ಗದಿನಮ್‌ ಚಕ್ರಹಸ್ತಮ್‌ ಇಚ್ಛಾಮಿ ತ್ವಾಮ್‌ ದ್ರಷ್ಟುಮ್‌ ಅಹಮ್‌ ತದಾ ಏವ।\n\nತೇನ ಏವ ರೂಪೇಣ ಚತುಃ ಭುಜೇನ ಸಹಸ್ರ ಬಾಹೋ ಭವ ವಿಶ್ವಮೂರ್ತೇ-ಮುಕುಟವಿಟ್ಟ, ಕೈಯಲ್ಲಿ ಗದೆ-ಚಕ್ರ\nತೊಟ್ಟ ನಿನ್ನನ್ನು ಆ ರೂಪದಲ್ಲೇ ಕಾಣಬಯಸುತ್ತೇನೆ. ಸಾವಿರ ತೋಳಿನ ವಿಶ್ವರೂಪನೇ, ಮತ್ತೊಮ್ಮೆ ನಾಲ್ಕು\nತೋಳಿನ ಅದೇ ರೂಪದಿಂದ ಕಾಣಿಸಿಕೋ.\n\n“ನೀನು ಹಿಂದೆ ಕಾಣಿಸಿಕೊಂಡಂತೆ ಚತುರ್ಭುಜನಾಗಿ, ಕಿರೀಟ ಧರಿಸಿದ ಗದಾ-ಚಕ್ರ ಹಿಡಿದಿರುವ ನಿನ್ನ ರೂಪವನ್ನು\nತೋರು” ಎಂದು ಅರ್ಜುನ ಸಹಸ್ರ ತೋಳಿನ ವಿಶ್ವರೂಪಿ ಭಗವಂತನಲ್ಲಿ ಕೈಜೋಡಿಸಿ ಬೇಡಿಕೊಳ್ಳುತ್ತಾನೆ. ಇಲ್ಲಿ\nಅರ್ಜುನ ಕೃಷ್ಣನಲ್ಲಿ -“ನಿನ್ನ ಚತುರ್ಭುಜ ರೂಪವನ್ನು ತೋರು” ಎಂದಿದ್ದಾನೆ. ಕೃಷ್ಣ ತನ್ನ ಅಂತರಂಗದ ಭಕ್ತರಿಗೆ\nತನ್ನ ಚತುರ್ಭುಜ ರೂಪವನ್ನು ತೋರಿದ್ದ. ಇದನ್ನು ಅರ್ಜುನ ಕೂಡಾ ನೋಡಿದ್ದಾನೆ. ಭಾಗವಶದಲ್ಲಿ-\nಬಾಲಕನಾಗಿದ್ದಾಗ ಕೃಷ್ಣ ತನ್ನ ಚತುರ್ಭುಜ ರೂಪವನ್ನು ತೋರಿದ್ದ ಎನ್ನುವುದನ್ನು ಹೀಗೆ ಹೇಳಿದ್ದಾರೆ:\n\nತಮದ್ಳು ತಂ ಬಾಲಕಮಂಬುಜೇಕ್ಷಣಂ ಚತುರ್ಭುಜಂ ಶಂಖಗದಾದ್ಯುದಾಯುಧಂ,\n\nಶ್ರೀವತ್ಸಲಕ್ಷ್ಮಂ ಗಲಶೋಭಿಕೌಸ್ತುಭಂ ಪೀತಾಂಬರಂ ಸಾಂದ್ರಪಯೋದಸೌಭಗಂ ॥೧೦.೦೩.೯॥\nಸಾಮಾನ್ಯರು ಕಾಣದ ಭಗವಂತನ ಚತುರ್ಭುಜ ರೂಪವನ್ನು ಕೃಷ್ಣ ಕೆಲವರಿಗೆ ತೋರಿದ್ದ ಎನ್ನುವುದನ್ನು ಈ\nಶ್ಲೋಕ ದೃಡಪಡಿಸುತ್ತದೆ. ಇಲ್ಲಿ ಅರ್ಜುನ ಭಗವಂತನಲ್ಲಿ ಆತನ ವಿಶ್ವರೂಪ ದರ್ಶನವನ್ನು ಕೊನೆಗೊಳಿಸಿ ತನಗೆ\nಚತುರ್ಭುಜ ರೂಪವನ್ನು ತೋರಿಸು ಎಂದು ಬೇಡಿಕೊಳ್ಳುತ್ತಾನೆ.\nಇಲ್ಲಿ ನಾವು ತಿಳಿಯಬೇಕಾದ ಮುಖ್ಯ ವಿಚಾರ ಎಂದರೆ: ಭಗವಂತನ ವಿಶ್ವರೂಪದ ಉಪಾಸನೆ ಸಾಮಾನ್ಯರಾದ\nನಮಗೆ ಅಸಾಧ್ಯ. ಆತನ ವಿಶ್ವರೂಪವನ್ನು ಮಹಾ ಜ್ಞಾನಿಯಾದ ಅರ್ಜುನನಿಂದಲೇ ನೋಡಿ ತಡೆದುಕೊಳ್ಳಲು\nಆಗಿಲ್ಲ. ಹಾಗಿರುವಾಗ ನಾವು ಅದನ್ನು ನಮ್ಮ ಧ್ಯಾನದಲ್ಲಿ ಜೀರ್ಣಿಸಿಕೊಳ್ಳವುದು ಸಾಧ್ಯವೇ? ಈ ಕಾರಣಕ್ಕಾಗಿ\nಧ್ಯಾನದಲ್ಲಿ ಭಗವಂತನ ವಿಶ್ವ ರೂಪವನ್ನು ಉಪಾಸನೆ ಮಾಡುವುದಕ್ಕಿಂತ, ಭಗವಂತನ ವಿಶ್ವ ಶಕ್ತಿಯ",
  "11.47": "ಭಗವಾನ್‌ ಉವಾಚ-ಭಗವಂತ ಹೇಳಿದನು:\n\nಮಯಾ ಪ್ರಸನ್ನೇನ ತವ ಅರ್ಜುನ ಇದಮ್‌ ರೂಪಮ್‌ ಪರಮ್‌ ದರ್ಶಿತಮ್‌ ಆತ್ಮಯೋಗಾತ್‌ |\n\nತೇಜಃ ಮಯಮ್‌ ವಿಶ್ವಮ್‌ ಅನಂತಮ್‌ ಆದ್ಯಮ್‌ ಯತ್‌ ಮೇ ತ್ವತ್‌ ಅನ್ಯೇನ ನ ದೃಷ್ಟ ಪೂರ್ವಮ್‌ -ಅರ್ಜುನಾ,\nನಾನೇ ಮೆಚ್ಚಿ ಆತ್ಮ ಶಕ್ತಿಯಿಂದ ನಿನಗೆ ತೋರಿಸಿದೆ ಈ ಹಿರಿಯ ರೂಪವನ್ನು. ಇದು ಬೆಳಕಿನ ಮೊತ್ತ. ಗುಣಗಳ\nಗುಂಪು. ಇದಕ್ಕೆ ಕೊನೆಯಿಲ್ಲ. ಇದು ಎಲ್ಲದಕ್ಕೂ ಮೊದಲು. ನನ್ನಿ 6 ರೂಪವನ್ನು ಇನ್ನಾ ರೂ ಈ ಮೊದಲು ಹೀಗೆ\nಕಂಡದ್ಲಿಲ್ಲ.\n\nಭಗವಂತನ ಸಂಹಾರ ರೂಪವನ್ನು ಕಂಡು ಭಯಗ್ರಸ್ತನಾಗಿರುವ ಅರ್ಜುನನನ್ನು ಕೃಷ್ಣ ಸಂತೈಸುತ್ತಾನೆ. ಕೃಷ್ಣ\nಹೇಳುತ್ತಾನೆ: “ನಾನು ನಿನಗೆ ವಿಶ್ವರೂಪ ತೋರಿದ್ದು ನಿನ್ನ ಭಕ್ತಿಗೆ ಪ್ರಸನ್ನನಾಗಿಯೇ ಹೊರತು, ನಿನ್ನನ್ನು\nಹೆದರಿಸುವುದಕ್ಕೋಸ್ಕರ ಅಲ್ಲ” ಎಂದು. ಕೃಷ್ಣ ತನ್ನ ಅವತಾರದಲ್ಲಿ ಅನೇಕ ಬಾರಿ ತನ್ನ ವಿಶ್ವರೂಪ ದರ್ಶನ\nತೋರಿದ್ದ. ಯಶೋದೆ-ಮಣ್ಣು ತಿಂದ ಕೃಷ್ಣನ ಬಾಯಿಯನ್ನು ತೆರೆಯಲು ಹೇಳಿದಾಗ, ಅಲ್ಲಿ ಆಕೆಗೆ ತನ್ನ\nಬಾಯಿಯಲ್ಲಿ ವಿಶ್ವರೂಪ ದರ್ಶನ ಮಾಡಿಸಿದ್ದ. ಇನ್ನೊಮ್ಮೆ ಹಾಲು ಕುಡಿದು ಆಕಳಿಸಿದ ಪುಟ್ಟ ಕೃಷ್ಣನ ಬಾಯಿಯಲ್ಲಿ\nಯಶೋದೆ ಭಗವಂತನ ವಿಶ್ವರೂಪ ದರ್ಶನ ಪಡೆದಿದ್ದಳು. ಸಂಧಾನಕ್ಕೆಂದು ದೃತರಾಷ್ಟ್ರನ ಸಭೆಗೆ ಬಂದ\nಕೃಷ್ಣನನ್ನು ದುರ್ಯೋಧನ ಬಂಧಿಸಲು ಪ್ರಯತ್ನಿಸಿದಾಗ, ಅಲ್ಲಿ ಕೃಷ್ಣ ತನ್ನ ವಿಶೇಷ ರೂಪವನ್ನು ತೋರಿದ್ದ. ಇಷ್ಟೇ\nಅಲ್ಲದೆ ಗರ್ಗಾಚಾರ್ಯರಿಗೆ, ಉದಂಕ ಮುನಿಗೆ ಕೂಡಾ ಕೃಷ್ಣನ ವಿಶ್ವರೂಪ ದರ್ಶನವಾಗಿತ್ತು. ಆದರೆ ಇಲ್ಲಿ\nಅರ್ಜುನನಿಗೆ ಕೃಷ್ಣ ತೋರಿದ ವಿಶ್ವರೂಪ ಎಲ್ಲಕ್ಕಿಂತ ಅಪರಿಮಿತವಾದುದು. “ಭೂಲೋಕದಲ್ಲಿ ಯಾರೂ ಈ\nಮೊದಲು ಹೀಗೆ ಕಂಡದ್ದಿಲ್ಲ ಎನ್ನುತ್ತಾನೆ” ಕೃಷ್ಣ. ಭಗವಂತನ ವಿಶ್ವರೂಪ-ಅದೊಂದು ಬೆಳಕಿನ ಪುಂಜ. ಅದು\nಗುಣಗಳ ಸಾಗರ. ಅನಂತವಾದ ಈ ವಿಶ್ವರೂಪ ದರ್ಶನವನ್ನು ಅರ್ಜುನ ಪಡೆದ.",
  "11.48": "ನವೇದ ಯಜ್ಞ ಅಧ್ಯಯನೆೈಃ ನದಾನ್ಯೆಃನ ಚ ಕ್ರಿಯಾಭಿಃ ನ ತಪೋಭಿಃ ಉಗ್ರೈಃ |\nಏವಮ್‌ ರೂಪಃ ಶಕ್ಯಃ ಅಹಮ್‌ ನೃಲೋಕೇ ದ್ರಷ್ಟುಮ್‌ ತ್ವತ್‌ ಅನ್ಯೇನ ಕುರು ಪ್ರವೀರ - ಕುರುವಂಶದ\nಕಡುಗಲಿಯೇ, ಭೂಲೋಕದಲ್ಲಿ ನೀನಲ್ಲದೆ ಇನ್ನಾರೂ ಇಂತಹ ಬಗೆಯ ನನ್ನನ್ನು ಕಾಣುವುದು ಸಾಧ್ಯವಿಲ್ಲ.\n\nಸಾಧ್ಯವಿಲ್ಲ ವೇದಗಳಲ್ಲಿ ಕರ್ಮಕಾಂಡವನ್ನರಸುವ ಕಲಿಕೆಗಳಿಂದ. ಇಲ್ಲ ಕೊಡುಗೆಗಳಿಂದ. ಇಲ್ಲ ನೇಮ\nನೋಂಪಿಗಳಿಂದ. ಇಲ್ಲ ಕಟ್ಟುನಿಟ್ಟಿನ ತಪಗಳಿಂದ.\n\nಭಗವಂತನ ಪ್ರೀತಿಗೆ ಪಾತ್ರರಾಗದ ಯಾರೂ ಆತನ ವಿಶ್ವರೂಪ ದರ್ಶನ ಪಡೆಯಲು ಸಾಧ್ಯವಿಲ್ಲ.\nವೇದಾಧ್ಯಯನದಿಂದ, ಯಜ್ಞದಿಂದ, ದಾನದಿಂದ ಇತ್ಯಾದಿ ಕರ್ಮದಿಂದ ಸರ್ವೋತ್ತಮನಾದ, ಸರ್ವ\nವಿಲಕ್ಷಣನಾದ ಭಗವಂತನ ವಿಶ್ವರೂಪ ದರ್ಶನ ಪಡೆಯುವುದು ಸಾಧ್ಯವಿಲ್ಲ. “ಅಂತಹ ನನ್ನ ರೂಪವನ್ನು ಕರ್ಮ\nನಿಷ್ಠನಾದ(ಕುರುಪ್ರವೀರ) ನೀನು ಕಂಡೆ” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.\n",
  "11.49": "ಮಾತೇ ವ್ಯಥಾ ಮಾ ಚ ವಿಮೂಢಭಾವಃ ದೃಷ್ಟ್ವಾ ರೂಪಮ್‌ ಘೋರಮ್‌ ಈದೃಕ್‌ ಮಮ ಇದಮ್‌ |\n\nವ್ಯಪೇತ ಭೀಃ ಪ್ರೀತ ಮನಾಃ ಪುನಃ ತ್ವಮ್‌ ತತ್‌ ಏವ ಮೇ ರೂಪಮ್‌ ಇದಮ್‌ ಪ್ರಪಶ್ಯ -ನಡುಗಿಸುವ ನನ್ನ\nಇಂತಹ ರೂಪವನ್ನು ಕಂಡು ಕಳವಳಿಸಬೇಡ; ಕಂಗೆಡಬೇಡ. ಮತ್ತೆ ನೀನು ನನ್ನ ಆ ಮೊದಲ ರೂಪವನ್ನೇ\nನೋಡು- ಅಂಜಿಕೆ ತೊರೆದು,ಬಗೆಯೊಳಕ್ಕರೆ ತುಂಬಿ.",
  "11.50": "ಸಂಜಯ ಉವಾಚ- ಸಂಜಯ ಹೇಳಿದನು:\n\nಇತಿ ಅರ್ಜುನಮ್‌ ವಾಸುದೇವಃ ತಥಾ ಉಕ್ತ್ವಾ ಸ್ವಕಮ್‌ ರೂಪಮ್‌ ದರ್ಶಯಾಮ್‌ ಆಸ ಭೂಯಃ ।\nಆಶ್ವಾಸಯಾಮ್‌ ಆಸ ಚ ಭೀತಮ್‌ ಏನಮ್‌ ಭೂತ್ವಾ ಪುನಃ ಸೌಮ್ಯವಪುಃ ಮಹಾತ್ಮಾ -ವಾಸುದೇವ ಹೀಗೆ\nನುಡಿದು ಮರಳಿ ಅರ್ಜುನನಿಗೆ ತನ್ನ ಕೃಷ್ಣ ರೂಪವನ್ನೇ ತೋರಿದ. ಮಹಾತ್ಮನಾದ ಕೃಷ್ಣ ಹೀಗೆ ಮರಳಿ\nಸೌಮ್ಯರೂಪ ತಾಳಿ ಅಂಜಿದ್ದ ಅರ್ಜುನನನ್ನು ಸಂತೈಸಿದ.\n\nಈ ಶ್ಲೋಕದಲ್ಲಿ ಸಂಜಯ ಭಗವಂತನನ್ನು ವಾಸುದೇವ ಎಂದು ಸಂಬೋಧಿಸಿದ್ದಾನೆ. ಭಗವಂತನ ಈ ನಾಮಕ್ಕೆ\nಅನೇಕ ಅರ್ಥಗಳಿವೆ. ವಾಸು-ದೇವ-ವಾಸುದೇವ. ಭಗವಂತ ವಾಸು, ಅಂದರೆ ತನ್ನನ್ನು ತಾನು\nಮುಚ್ಚಿಕೊಂಡವನು. ಯಾವಾಗ ನಾವು ಸಂಸಾರ ಬಂಧನದ ಹದಿನೈದು ಬೇಲಿಗಳನ್ನು ದಾಟಿ, ಸಮಾಧಿ\n\nಸ್ಥಿತಿಯಿಂದ ಆಳಕ್ಕಿಳಿದು, ಹದಿನಾರನೇ ಜೀವಸ್ವರೂಪವನ್ನು ಕಾಣುತ್ತೇವೋ, ಆಗ ಭಗವಂತನ\nಸಾಕ್ಷಾತ್ಕಾರವಾಗುತ್ತದೆ. ಈ ಸ್ಥಿತಿಯಲ್ಲಿ ಮುಚ್ಚಿಕೊಂಡ ಭಗವಂತ ದೇವನಾಗಿ ತೆರೆದುಕೊಳ್ಳುತ್ತಾನೆ.\nಭಗವಂತನನ್ನು ಕಾಣಬೇಕಾದರೆ ಮೊದಲು ನಾವು ನಮ್ಮನ್ನು ಕಾಣಬೇಕು. ನಮ್ಮ ಅರಿವೇ ನಮಗಿಲ್ಲದೆ\nಭಗವಂತನನ್ನು ಕಾಣುವುದು ಅಸಾಧ್ಯ. ನಾವು ನಮ್ಮ ಜೀವಸ್ವರೂಪವನ್ನು ಕಂಡಾಗ, ಅದರೊಳಗಿನಿಂದ\nಸಾಕ್ಷಾತ್ಮಾರವಾಗುವ ಭಗವಂತ ದೇವಃ. ನಾವು ನಮ್ಮ ಪಂಚಕೋಶಗಳ(ಅನ್ನಮಯ ಕೋಶ, ಪ್ರಾಣಮಯ\nಕೋಶ , ವಿಜ್ಞಾನಮಯ ಕೋಶ, ಮನೋಮಯ ಕೋಶ ಹಾಗೂ ಆನಂದಮಯ ಕೋಶ) ಪರದೆಯಲ್ಲಿದ್ದಾಗ\nವಾಸುವಾಗಿ; ಪರದೆಯಿಂದಾಚೆಗೆ ಬಂದು ಜೀವ ಸ್ವರೂಪವನ್ನು ಕಂಡಾಗ ದೇವನಾಗಿ ದರ್ಶನ ಕೊಡುವ\nಭಗವಂತ ವಾಸುದೇವಃ.",
  "11.51": "ಅರ್ಜುನಃ ಉವಾಚ-ಅರ್ಜುನ ಹೇಳಿದನು:\n\nದೃಷ್ಟ್ವಾ ಇದಮ್‌ ಮಾನುಷಮ್‌ ರೂಪಮ್‌ ತವ ಸೌಮ್ಯಮ್‌ ಜನಾರ್ದನ ।\n\nಇದಾನೀಮ್‌ ಅಸ್ಮಿ ಸಂವೃತ್ತಃ ಸಚೇತಾಃ ಪ್ರಕೃತಿಮ್‌ ಗತಃ -ಜನಾರ್ದನಾ, ಮನುಷ್ಯಾಕಾರದ ನಿನ್ನ ಈ\nಸೌಮ್ಯರೂಪವನ್ನು ಕಂಡು ಜೀವ ಬಂತು. ಈಗ ಚೇತರಿಸಿಕೊಂಡು ಸಹಜ ಸ್ಥಿತಿಗೆ ಮರಳುತ್ತಿದ್ದೇನೆ.\n\nಇಲ್ಲಿ ಅರ್ಜುನ ಭಗವಂತನನ್ನು ಜನಾರ್ದನ ಎಂದು ಸಂಬೋಧಿಸಿದ್ದಾನೆ. ಜನ-ಅರ್ದನ-ಜನಾರ್ದನ. ಇಲ್ಲಿ\nಅರ್ದನ ಅಂದರೆ ಕೊನೆಗೊಳಿಸುವವನು ಎನ್ನುವ ಅರ್ಥವನ್ನು ಕೊಡುತ್ತದೆ. 'ಜನ' ಅನ್ನುವ ಪದಕ್ಕೆ ಅನೇಕ\nಅರ್ಥಗಳಿವೆ. ಜನ ಅಂದರೆ ದುರ್ಜನ. ಜನಾರ್ದನ ಅಂದರೆ ದುರ್ಜನ ನಾಶಕ. ಜನ ಅಂದರೆ ಜನನ ಉಳ್ಳವರು.\nಜನಾರ್ದನ ಎಂದರೆ ಜನನ ಮುಕ್ತಗೊಳಿಸುವವನು ಅಂದರೆ ಮುಕ್ತಿಪ್ರದಾಯಕ. \"ದುರ್ಜನರ ಸಂಹಾರಕ್ಕೆಂದು\nನಿಂತಿರುವ ನಿನ್ನ ಆ ರೂಪವನ್ನು ಕಂಡು ನಾನು ಭಯಗೊಂಡಿದ್ದೆ. ಭಕ್ತರ ಕರೆಗೆ ಓಗೊಟ್ಟು, ತನ್ನ ಭಕ್ತರಿಗೆ\nಮೋಕ್ಷವನ್ನು ಕರುಣಿಸುವ ನಿನ್ನ ಈ ಸೌಮ್ಯ ರೂಪವನ್ನು ಕಂಡು ನಾನು ಚೇತರಿಸಿಕೊಂಡೆ”- ಎನ್ನುವ ಭಾವ ಈ\nಸಂಬೋಧನೆಯಲ್ಲಿದೆ.\nಭಗವಾನುವಾಚ ।\nಸುದುರ್ದರ್ಶಮಿದಂ ರೂಪಂ ದೃಷ್ಟವಾನಸಿ ಯನ್ಮಮ |\n\nದೇವಾ ಅಪ್ಯ",
  "11.52": "[ಬನ್ನಂಜೆಯವರ ಭಾಷ್ಯದಲ್ಲಿ ಹನ್ನೊಂದನೇ ಅಧ್ಯಾಯವು ೩೫ ಶ್ಲೋಕಗಳೊಂದಿಗೆ ಮುಕ್ತಾಯಗೊಳ್ಳುತ್ತದೆ. ೧೧.೫೨ನೆಯ ಶ್ಲೋಕವು ಒಸಿಆರ್ ದೋಷದಿಂದ ಬಂದದ್ದಾಗಿದ್ದು, ೧೧.೫೧ನೆಯ ಶ್ಲೋಕವೇ ಕೊನೆಯದ್ದಾಗಿದೆ.]",
  "11.53": "ಭಗವಾನುವಾಚ-ಭಗವಂತ ಹೇಳಿದನು:\n\nಸುದುರ್ದರ್ಶಮ್‌ ಇದಮ್‌ ರೂಪಮ್‌ ದೃಷ್ಟವಾನ್‌ ಅಸಿ ಯತ್‌ ಮಮ |\n\nದೇವಾಃ ಅಪಿ ಅಸ್ಯ ರೂಪಸ್ಯ ನಿತ್ಯಮ್‌ ದರ್ಶನ ಕಾಂಕ್ಷಿಣಃ ॥\n\nನ ಅಹಂ ವೇದೈಃ ನ ತಪಸಾ ನ ದಾನೇನ ನ ಚ ಇಜ್ಯಯಾ |\n\nಶಕ್ಯಃ ಏವಂ ವಿಧಃ ದ್ರಷ್ಟುಮ್‌ ದೃಷ್ಟವಾನ್‌ ಅಸಿ ಮಾಮ್‌ ಯಥಾ --ನೀನು ಕಂಡ ನನ್ನ ಈ ರೂಪ ಸುಲಭವಾಗಿ\nಕಾಣಬರುವಂತದಲ್ಲ. ದೇವತೆಗಳು ಕೂಡಾ ಈ ರೂಪವನ್ನು ಕಾಣಲೆಂದು ಅನುಗಾಲ ಕಾಯುತ್ತಿರುತ್ತಾರೆ.\n\nನೀನು ಕಂಡ ಹಾಗೆ ಈ ಬಗೆಯ ನನ್ನ ನ್ನು ಕಾಣಲು ಬರಿದೆ ವೇದಗಳನ್ನೊ ೀದುವುದರಿಂದ ಸಾಧ್ಯವಿಲ್ಲ. ಇಲ್ಲ\nತಪಸ್ಸಿನಿಂದ, ಇಲ್ಲ ದಾನದಿಂದ, ಇಲ್ಲ ಯಜ್ಞದಿಂದಲೂ.\n\nಭಗವಂತ ಅರ್ಜುನನಿಗೆ ಕಾಣಿಸಿದ ತನ್ನ ಅಪೂರ್ವ ರೂಪ ಬಹಳ ದುರ್ಲಭರೂಪ. ಇಂತಹ ಅಪೂರ್ವ\nರೂಪವನ್ನು ಕಾಣಲು ದೇವತೆಗಳೂ ಕೂಡಾ ಆಸೆಯಿಂದ ಅನುಗಾಲ ಕಾಯುತ್ತಿರುತ್ತಾರೆ. ಕೃಷ್ಣ ಇಲ್ಲಿ ಮತ್ತೆ ಒತ್ತು\nಕೊಟ್ಟು ಹಿಂದೆ ಹೇಳಿದ ವಿಚಾರವನ್ನು ಮರಳಿ ಹೇಳುತ್ತಾನೆ. “ಸ್ವಸಾಮರ್ಥ್ಯದಿಂದ(ವೇದಾಧ್ಯಾಯನ, ಯಜ್ಞ,\nದಾನ, ತಪಸ್ಸು ಇತ್ಯಾದಿ ಕರ್ಮಗಳನ್ನು ಮಾಡುವ ಮುಖೇನ) ನನ್ನ ಈ ವಿಶಿಷ್ಠ ರೂಪವನ್ನು ಕಾಣಲು\nಸಾಧ್ಯವಿಲ್ಲ'ವನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.",
  "11.54": "ಭಕ್ತ್ಯಾ ತು ಅನನ್ಯಯಾ ಶಕ್ಯಃ ಅಹಂ ಏವಮ್‌ ವಿಧಃ ಅರ್ಜುನ ।\n\nಜ್ಞಾತುಮ್‌ ದ್ರಷ್ಟುಮ್‌ ಚ ತತ್ತ್ವೇನ ಪ್ರವೇಷ್ಟುಮ್‌ ಚ ಪರಂತಪ -ಅರಿಗಳನ್ನು ಸುಟ್ಟುರಿಯುವ ಅರ್ಜುನಾ,\nನನ್ನನ್ನು ಈ ಪರಿ ಸರಿಯಾಗಿ ಅರಿಯಲು, ಅರಿತು ಕಾಣಲು, ಕಂಡು ಸೇರಲು ನನ್ನಲ್ಲೇ ನೆಲೆಗೊಂಡ ಭಕ್ತಿಯಿಂದ\nಮಾತ್ರವೇ ಸಾಧ್ಯ.\n\nಭಗವಂತನನ್ನು ಕಾಣಲು ಇರುವ ಮೂಲ ಮಂತ್ರ 'ಭಕ್ತಿ'. ಏಕನಿಷ್ಠೆಯಿಂದ ಭಗವಂತನನ್ನು ಅನನ್ಯವಾಗಿ ಭಕ್ತಿ\nಮಾಡುವುದರಿಂದ ಆತನನ್ನು ಸೇರಲು ಸಾಧ್ಯ. ಎಲ್ಲರಿಗೂ ಮಿಗಿಲಾದ ಭಗವಂತ ಭಕ್ತ ಪರಾಧೀನ.",
  "11.55": "ಮತ್‌ ಕರ್ಮ ಕೃತ್‌ ಮತ್‌ ಪರಮಃ ಮತ್‌ ಭಕ್ತಃ ಸಂಗವರ್ಜಿತಃ |\n\nನಿರ್ವೈರಃ ಸರ್ವಭೂತೇಷು ಯಃ ಸ ಮಾಮ್‌ ಏತಿ ಪಾಂಡವ -ಓ ಪಾಂಡವಾ, ಎಲ್ಲವನ್ನು ನನಗಾಗಿ\nಮಾಡುವವನು, ನನ್ನನ್ನೇ ಪರದೈವವೆಂದು ತಿಳಿದವನು, ವಿಷಯದ ನಂಟು ತೊರೆದು ನನ್ನಲ್ಲಿ ಭಕ್ತಿಯಿಟ್ಟವನು,\nಯಾವ ಜೀವಿಗಳಲ್ಲೂ ಹಗೆಗೊಳ್ಳದವನು -ನನ್ನನ್ನು ಪಡೆಯುತ್ತಾನೆ.\n\nಭಗವಂತನನ್ನು ಕಾಣಲು ಭಕ್ತಿಯ ಜೊತೆಗೆ ಇರುವ ಅತಿಮುಖ್ಯವಾದ ಅಂಶವನ್ನು ಕೃಷ್ಣ ಇಲ್ಲಿ ವಿವರಿಸುತ್ತಾನೆ.\nನಾವು ಮಾಡುವ ಕಾರ್ಯವನ್ನು “ನಾನು ಮಾಡಿದೆ' ಎಂದು ಅಹಂಕಾರ ಪಡದೆ, ಭಗವಂತ ನನ್ನ ಕೈಯಿಂದ\nಮಾಡಿಸಿದ ಎನ್ನುವ ಅನುಸಂಧಾನ; ಅರ್ಪಣ ಭಾವ, ಫಲದ ಅಪೇಕ್ಷೆ ಇಲ್ಲದ ಭಕ್ತಿ, ದ್ವೇಷ ಪ್ರತೀಕಾರವಿಲ್ಲದೆ\n\nಭಗವಂತನಲ್ಲಿ ಶರಣಾಗತಿ, ನಿರ್ಲಿಪ್ತ ಭಾವದಿಂದ ಭಗವಂತ ಸರ್ವೋತ್ತಮ ಎನ್ನು ವ ಸತ್ಯವನ್ನ ರಿತು ಆತನನ್ನು\nಪ್ರೀತಿಸುವುದು-ಇದರಿಂದ ಭಗವಂತನನ್ನು ಕಾಣಲು ಸಾಧ್ಯ.",
  "12.1": "ಅರ್ಜುನಃ ಉವಾಚ -ಅರ್ಜುನ ಕೇಳಿದನು:\n\nಏವಮ್‌ ಸತತ ಯುಕ್ತಾಃ ಯೇ ಭಕ್ತಾಃ ತ್ವಾಮ್‌ ಪರ್ಯುಪಾಸತೇ।\n\nಯೇ ಚ ಅಪಿ ಅಕ್ಷರಮ್‌ ಅವ್ಯಕ್ತಮ್‌ ತೇಷಾಮ್‌ ಕೇ ಯೋಗವಿತ್ತಮಾಃ -ಹೀಗೆ ನಿರಂತರ ಸಾಧನೆಯಿಂದ\nನಿನ್ನನ್ನು ಸೇವಿಸುವವರು ಭಕ್ತರು ಮತ್ತು ಅಳಿವಿರದ ಅವ್ಯಕ್ತತತ್ವ(ಶ್ರೀತತ್ವ)ದ ಉಪಾಸಕರು. ಇವರಲ್ಲಿ ಯಾರು\nಹೆಚ್ಚಿನವರು.\n\nಈ ಶ್ಲೋಕವನ್ನು ಮೇಲ್ನೋಟದಲ್ಲಿ ನೋಡಿದರೆ ಭಗವಂತನ ವಿಶಿಷ್ಟರೂಪದ ಉಪಾಸನೆ ಮತ್ತು ಯಾವುದೇ\nರೂಪಗಳಿಂದ ವ್ಯಕ್ತವಾಗದ ನಿರಾಕಾರ ಭಗವಂತನ ಉಪಾಸನೆ-ಇವೆರಡರಲ್ಲಿ ಯಾವುದು ಸೂಕ್ತ ಎಂದು\n\nಕೇಳಿದಂತೆ ಕಾಣುತ್ತದೆ. ಆದರೆ ಈ ಶ್ಲೋಕದಲ್ಲಿ ಅರ್ಜುನ ಕೇಳುತ್ತಿರುವ ಮೂಲ ಪ್ರಶ್ನೆಯೇ ಬೇರೆ. ಇದನ್ನು\nಮಧ್ವಾಚಾರ್ಯರು ವಿಶಿಷ್ಟವಾಗಿ ವಿವರಿಸಿದ್ದಾರೆ.\n\nಭಗವಂತನ ಚಿಂತನೆ ಮಾಡುವವರೆಲ್ಲಾ ಭಗವದ್‌ ಭಕ್ತರಾಗಿರಬೇಕೆಂದೇನಿಲ್ಲ... ಭಗವಂತನ ಚಿಂತನೆ\nಮಾಡುವುದಕ್ಕೆ ಬೇಕಾಗಿರುವ ಮೂಲದ್ರವ್ಯ ಪ್ರೀತಿ. ಜ್ಞಾನಪೂರ್ವಕವಾದ ಪ್ರೀತಿಯೇ-ಭಕ್ತಿ. ಹಿಂದಿನ ಕಾಲದಲ್ಲಿ\nಪ್ರತಿಯೊಬ್ಬರ ಮನೆಯ ದೇವರ ಕೋಣೆಯಲ್ಲೊಂದು ವಿಗ್ರಹವಿರುತ್ತಿತ್ತ. ಅವರವರ ಉಪಾಸನೆಗೆ ಯಾವುದು\nಇಷ್ಟವೋ ಅಂತಹ ಇಷ್ಟದೇವತೆಯ ವಿಗ್ರಹ. ನಾವು ಈ ಅಂಶವನ್ನು ವಿಶ್ಲೇಷಿಸಿದರೆ ಏಕೆ ಈ ರೀತಿ ಪ್ರತಿಮೆಯನ್ನು\nಇಟ್ಟು ಪೂಜಿಸುತ್ತಿದ್ದರು ಎನ್ನುವುದು ತಿಳಿಯುತ್ತದೆ. ಇಲ್ಲಿ ಮೊದಲು ನಾವು ನಮ್ಮ ಮನಸ್ಸು ಹೇಗೆ ಕೆಲಸ\nಮಾಡುತ್ತದೆ ಎನ್ನುವ ವಿಚಾರವನ್ನು ತಿಳಿದುಕೊಳ್ಳಬೇಕು. ಕಣ್ಣಿನಿಂದ ನೋಡದ್ದನ್ನು ಮನಸ್ಸು ಗ್ರಹಿಸುವುದಿಲ್ಲ.\nಉದಾಹರಣೆಗೆ ಭಗವಂತ 'ಅತ್ಯಂತ ಸುಂದರ' ಎಂದು ತಿಳಿದು ನಾವು ಕಣ್ಣುಮುಚ್ಚಿ ಧ್ಯಾನಕ್ಕೆಕುಳಿತರೆ, ನಮ್ಮ\nಮನಸ್ಸು ನಾವು ನೋಡಿದ ಯಾವುದೋ ಒಬ್ಬ ಸುಂದರ ಮನುಷ್ಯನನ್ನು ನಮಗೆ ತೋರಿಸುತ್ತದೆ! ಇದಕ್ಕಾಗಿ\nಹಿಂದಿನವರು ಭಗವಂತನಿಗೆ ನಮ್ಮಂತೆ ಕರಚರಣಗಳಿವೆ, ಆದರೆ ಆತ ಯಾವ ಮನುಷ್ಯರಂತೆಯೂ ಇಲ್ಲ\nಎನ್ನುವಂತೆ ಆತನ ಪ್ರತಿಮೆಯನ್ನು ಕಡೆದರು. ಈ ಪ್ರತಿಮೆಯನ್ನು ನೆನಪಿನಲ್ಲಿಟ್ಟುಕೊಂಡು ಕಣ್ಣುಮುಚ್ಚಿ\nಭಗವಂತನ ಗುಣಾನುಸಂಧಾನ ಮಾಡಿದರೆ, ನಮಗೆ ಕೇವಲ ಆ ಮೂರ್ತಿ ಕಾಣಿಸುತ್ತದೆಯೇ ಹೊರತು ನಮ್ಮ\nಪರಿಚಯದ ವ್ಯಕ್ತಿಯಲ್ಲ. ಇದರಿಂದ ಧ್ಯಾನ ಸುಲಭಸಾಧ್ಯವಾಗುತ್ತದೆ. ಮನಸ್ಸು ಯಾವುದೋ ವ್ಯಕ್ತಿಯನ್ನು\nಚಿಂತಿಸದೆ ಪ್ರತಿಮೆಯ ರೂಪದಲ್ಲಿ ಭಗವಂತನನ್ನು ಕಾಣಲಾರಂಭಿಸುತ್ತದೆ. ಈ ಕಾರಣಕ್ಕಾಗಿ ಭಗವಂತನ\nಚಿಂತನೆ ಮಾಡಲು ಒಂದು ರೂಪ ಅಗತ್ಯ.\n\nನಮಗೆ ತಿಳಿದಂತೆ ಮಾತೆ ಶ್ರೀಲಕ್ಷ್ಮಿಯನ್ನು ಶ್ರೀತತ್ವ, ಅಕ್ಷರಳು, ಅವ್ಯಕ್ತಳು, ಪ್ರಕೃತಿ, ಹ್ರೀ, ಇತ್ಯಾದಿ ಅನೇಕ\nಹೆಸರಿನಿಂದ ಕರೆಯುತ್ತಾರೆ. ಭಗವದ್ಗೀತೆಯಲ್ಲೇ ಅನೇಕ ಕಡೆ ಈ ರೀತಿಯ ಸಂಬೋಧನೆ ಕಾಣಸಿಗುತ್ತವೆ.\nಕಠೋಪನಿಷತ್ತಿನಲ್ಲಿ ಹೇಳುವಂತೆ \"ಮಹತಃ ಪರಮವ್ಯಕ್ತಮವ್ಯಕ್ತಾತ್ಪುರುಷಃ ಪರಃ\" . ಅಂದರೆ ಮಹತತ್ವಕ್ಕಿಂತ\nಅವ್ಯಕ್ತ ತತ್ವ ಹಿರಿದು, ಅವ್ಯಕ್ತ ತತ್ವಕ್ಕಿಂತ ಪುರುಷನಾದ ಭಗವಂತ ಹಿರಿಯ. ಇಲ್ಲಿ ಸ್ಪಷ್ಟವಾಗಿ ನಮಗೆ\nತಿಳಿವುದೇನೆಂದರೆ-ಅವ್ಯಕ್ತಳು, ಅಕ್ಷರಳು ಎಂದರೆ ಮಾತೆ ಶ್ರೀಲಕ್ಷ್ಮಿ.\n\nನಿರಂತರವಾಗಿ ಮನಸ್ಸಿನಲ್ಲಿ ನೀನು ಹೇಳಿರುವ ಗುಣಗಳ ಅನುಸಂಧಾನ ಮಾಡುತ್ತಾ, ಶಾಸ್ತ್ರಗಳ ಮೂಲಕ ನಿನ್ನ\nಮಹಿಮೆಯನ್ನು, ನಿನ್ನ ರೂಪ ವಿಶೇಷಗಳನ್ನು ತಿಳಿದುಕೊಂಡು, ಅದರಲ್ಲಿ ಭಕ್ತಿಯನ್ನು ಬೆಳೆಸಿಕೊಂಡು, ನಿನ್ನ\nಉಪಾಸನೆ ಮಾಡಿದರೆ ಒಳ್ಳೆಯದೋ; ಅಥವಾ ಕ್ಷರಾತೀತ(ಅಕ್ಷರ)ಳಾದ ಶ್ರೀತತ್ವದ ಉಪಾಸನೆ ಒಳ್ಳೆಯದೋ.\nಯಾವ ದಾರಿ ಹೆಚ್ಚು ಸೂಕ್ತ-ಎನ್ನುವುದು ಅರ್ಜುನನ ಪ್ರಶ್ನೆ.",
  "12.2": "ಭಗವಾನ್‌ ಉವಾಚ-ಭಗವಂತ ಹೇಳಿದನು:\n\nಮಯಿ ಆವೇಶ್ಯ ಮನಃ ಯೇ ಮಾಮ್‌ ನಿತ್ಯ ಯುಕ್ತಾಃ ಉಪಾಸತೇ ।\n\nಶ್ರದ್ಧಯಾ ಪರಯಾ ಉಪೇತಾಃ ತೇ ಮೇ ಯುಕ್ತಃ ತಮಾಃ ಮತಾಃ -ನನ್ನಲ್ಲಿ ಬಗೆಯಿಟ್ಟವರು, ತುಂಬು\nನಂಬಿಕೆಯಿಂದ ಕೂಡಿ. ನನ್ನನ್ನೇ ಸೇವಿಸುವ. ನಿರಂತರ ಸಾಧಕರು-ಅತ್ಯಂತ ಪರಿಪೂರ್ಣರೆಂದು\nಪರಿಗಣಿತರಾಗುತ್ತಾರೆ.\n\nಕೃಷ್ಣ ಅರ್ಜುನನ ಪ್ರಶ್ನೆಗೆ ಉತ್ತರ ಕೊಡುತ್ತಾ ಹೇಳುತ್ತಾನೆ: “ಶ್ರದ್ಧೆಯಿಂದ ಯಾರು ನನ್ನನ್ನು ಉಪಾಸನೆ\nಮಾಡುತ್ತಾರೋ ಅವರು ಭಗವಂತನ ಸಾಧಕರಲ್ಲಿ ಶ್ರೇಷ್ಠರು” ಎಂದು. ಇಲ್ಲಿ ಶ್ರದ್ಧೆ ಎಂದರೆ ನಂಬಿಕೆ.\nಸಾಧನೆಯಲ್ಲಿ ಬಹಳ ಮುಖ್ಯವಾದದ್ದು ಶ್ರದ್ಧೆ. ಶ್ರದ್ಧೆ ಇಲ್ಲದೆ ಉಪಾಸನೆ ಮಾಡಿ ಉಪಯೋಗವಿಲ್ಲ. ಇದು\nಮನಃಶಾಸ್ತ್ರ. ಇದಕ್ಕೆ ಲೌಕಿಕವಾದ ಉದಾಹರಣೆ: ರೋಗಿ ಮತ್ತು ವೈದ್ಯರು. ಒಂದು ವೇಳೆ ರೋಗಿಗೆ ತನ್ನನ್ನು\nಪರೀಕ್ಷಿಸಿ ಔಷಧ ಕೊಡುವ ವೈದ್ಯನ ಮೇಲೆ ನಂಬಿಕೆ ಇಲ್ಲದಿದ್ದರೆ, ತೆಗೆದುಕೊಳ್ಳುವ ಔಷಧ ಆತನಲ್ಲಿ ಕೆಲಸ\nಮಾಡುವುದಿಲ್ಲ. ಗಾಢವಾದ ನಂಬಿಕೆ ಇದ್ದರೆ-ವೈದ್ಯ ಯಾವ ಕಾಯಿಲೆಗೆ ಯಾವ ಮದ್ದು ಕೊಟ್ಟರೂ ರೋಗ\nಗುಣವಾಗುತ್ತದೆ! ಇದು ವೈಜ್ಞಾನಿಕವಾಗಿ ಕೂಡಾ ಸಾಬೀತಾಗಿರುವ ವಿಷಯ. ಆದ್ದರಿಂದ ಕೇವಲ ಕಣ್ಮುಚ್ಚಿ-\nನಂಬಿಕೆ ಇಲ್ಲದೆ ಉಪಾಸನೆ ಮಾಡಿದರೆ ಉಪಯೋಗವಿಲ್ಲ. ದೃಢವಾದ ಶ್ರದ್ಧೆಯಿಂದ, ತಿಳಿದು, ಭಗವಂತನ\nಗುಣರೂಪವನ್ನು ಧ್ಯಾನ ಮಾಡುವುದು ಶ್ರೇಷ್ಠ ಭಕ್ತಿ ಎನಿಸುತ್ತದೆ. ಪೂರ್ಣ ಶ್ರದ್ಧೆಯಿಂದ ಯಾವ ರೂಪದಿಂದಲೂ,\nಯಾವ ನಾಮದಿಂದಲೂ ಭಗವಂತನನ್ನು ಉಪಾಸನೆ ಮಾಡಬಹುದು. ಭಗವಂತನ ರೂಪವಲ್ಲದ\nರೂಪವೊಂದಿಲ್ಲ, ಭಗವಂತನ ನಾಮವಲ್ಲದ ನಾಮವೊಂದಿಲ್ಲ. ಪೂರ್ಣ ಶ್ರದ್ಧೆ ಇದ್ದಾಗ ನಾಮ-ರೂಪ\nಸಮಸ್ಯೆಯಾಗುವುದಿಲ್ಲ. ಹೀಗಾಗಿ ಭಗವಂತ ಹೇಳುತ್ತಾನೆ: “ನನ್ನ ರೂಪ ಮತ್ತು ಗುಣ ವಿಶೇಷವನ್ನು ಯಾರು\nಶ್ರದ್ಧೆಯಿಂದ ಉಪಾಸನೆ ಮಾಡುತ್ತಾರೋ ಅವರು ಸಾಧಕರಲ್ಲಿ ಶ್ರೇಷ್ಠರು” ಎಂದು.",
  "12.3": "ಯೇತು ಅಕ್ಷರಮ್ ಅನಿರ್ದೇಶ್ಯಮ್ ಅವ್ಯಕ್ತಮ್ ಪರ್ಯುಪಾಸತೇ ।\nಸರ್ವತ್ರಗಮ್ ಆಚಿಂತ್ಯಮ್ ಚ ಕೂಟಸ್ಥಮ್ ಅಚಲಮ್ ಧ್ರುವಮ್ -- ಅವ್ಯಕ್ತವೂ ಅಳಿವಿರದ ತತ್ತ್ವ. ಮಾತಿಗೆ ನಿಲುಕದ, ಚಿಂತನೆಗೆ ಎಟುಕದ ತತ್ತ್ವ. ಆಗಸದಲ್ಲಿ ನೆಲೆಸಿ ಎಲ್ಲೆಡೆಯೂ ತುಂಬಿರುವಂತಾದ್ದು. ನೆಲೆಗೆಡದ ನಿರ್ವಿಕಾರವಾದ ಪರತತ್ತ್ವ.\n\nಅವ್ಯಕ್ತತತ್ತ್ವ ಲಕ್ಷ್ಮಿಯ ಉಪಾಸನೆಯ ಬಗ್ಗೆ ಇಲ್ಲಿ ಕೃಷ್ಣ ವಿವರಿಸುತ್ತಾನೆ. ಲೋಕನೀತಿಗೂ ಭಗವಂತನ ಉಪಾಸನೆಯಲ್ಲೂ ಒಂದು ವ್ಯತ್ಯಾಸವಿದೆ. ಲೋಕದಲ್ಲಿ ಸಾಮಾನ್ಯವಾಗಿ ತಾಯಿ ಯಾವಾಗಲೂ ತನ್ನ ಮಕ್ಕಳ ತಪ್ಪನ್ನು ಕ್ಷಮಿಸುತ್ತಾಳೆ ಮತ್ತು ತಂದೆ ಶಿಕ್ಷಿಸುತ್ತಾನೆ. ಆದರೆ ತಾಯಿ ಶ್ರೀಲಕ್ಷ್ಮಿ ಉಪಾಸನೆ ಮತ್ತು ಭಗವಂತನ ಉಪಾಸನೆಯಲ್ಲಿ ಇದು ವ್ಯತಿರಿಕ್ತ. ಉಪಾಸನೆಯಲ್ಲಿ ಏನಾದರೂ ಲೋಪ ದೋಷಗಳಾದರೆ ಮಾತೆ ಕ್ಷಮಿಸಲಾರಳು, ಆದರೆ ಭಗವಂತ ಕ್ಷಮಿಸುತ್ತಾನೆ. ಈ ಕಾರಣಕ್ಕಾಗಿ ಅವ್ಯಕ್ತಳಾದ ಅಕ್ಷರಳ ಉಪಾಸನೆ ಕಷ್ಟ.",
  "12.4": "ಭಗವಂತ ಈ ಪ್ರಪಂಚವನ್ನು ಸೃಷ್ಟಿ ಮಾಡಿ, ಹದಿನೈದು ಬೇಲಿಗಳ ಈ ಸಂಸಾರದಲ್ಲಿ ಜೀವವನ್ನು ಇಟ್ಟ. ಈ\nಹದಿನೈದು ಬೇಲಿಗಳೆಂದರೆ:\n\n1. ಶ್ರದ್ಧೆಯ ಬೇಲಿ: ಕಿತ್ತೆಸೆಯಲು ಆಗದ ಬೇಲಿ- ಜೀವ ಸ್ವಭಾವದಿಂದ ಬಂದ ಶ್ರದ್ಧೆ. ಮತ್ತು ಕಿತ್ತೆಸೆಯಬೇಕಾದ\nಬೇಲಿ-ಮನೆತನ ಕುಟುಂಬ , ಬೆಳೆದ ವಾತಾವರಣದ ಪ್ರಭಾವದಿಂದ ಬಂದ ಶ್ರದ್ಧೆ.\n\n2-6. ಪಂಚಭೂತಗಳ ಬೇಲಿ : ಮಣ್ಣು-ನೀರು( ಅನ್ನಮಯ ಕೋಶ) ಬೆಂಕಿ-ಗಾಳಿ-ಆಕಾಶ(ಪ್ರಾಣಮಯ ಕೋಶ).\n7. ಇಂದ್ರಿಯಗಳ ಬೇಲಿ: ಐದು ಜ್ಞಾನೇಂದ್ರಿಯಗಳು ಐದು ಕರ್ಮೇಂದ್ರಿಯಗಳು.\n\n8. ಅಂತಃಕರಣದ ಬೇಲಿ: ಕೆಟ್ಟದ್ದನ್ನು ಯೋಚಿಸುವ ಮನಸ್ಸು\n\n9. ಅನ್ನದ ಬೇಲಿ: ಆಹಾರ\n\n10. ವೀರ್ಯದ ಬೇಲಿ: ಶಕ್ತಿ\n\n11. ತಪಃ : ಹಾಗಾಗಬೇಕು ಹೀಗಾಗಬೇಕು ಅನ್ನುವ ಆಲೋಚನೆ (ತಿರುಕನ ಕನಸಿನಂತೆ).\n\n12. ಮಂತ್ರಃ :ತನ್ನ ಕನಸನ್ನು ನನಸು ಮಾಡಲು ಆಡುವ ಮಾತುಗಾರಿಕೆ.\n\n13. ಕರ್ಮಃ : ಕನಸನ್ನು ಸಾಧಿಸಲು ಮಾಡುವ ಕರ್ಮ.\n\n14. ಲೋಕಗಳು : ಸ್ತಿರ-ಚರ ಸೊತ್ತುಗಳು (ನಾನು ಮಾಡಿದ್ದು, ನನ್ನದು ಅನ್ನುವ ಸೊತ್ತುಗಳು)\n\n15. ನಾಮದ ಬೇಲಿ : ಕೀರ್ತಿ(Reputation).\n\nಈ ಹದಿನೈದು ಬೇಲಿಯ ಒಳಗೆ ಸಿಕ್ಕಿ ಹಾಕಿಕೊಂಡಿರುವ ಹದಿನಾರನೆಯದಾದ “ಕ್ಷರ” ಜೀವನಿಗೆ ಈ ಮೇಲಿನ\nಬೇಲಿ ಎನ್ನುವ ಅಂಗಿ ಹಾಕಿ ಈ ಪ್ರಪಂಚಕ್ಕೆ ಕಳಿಸಿರುವ ಚಿತ್‌ ಪ್ರಕೃತಿ ಹದಿನೇಳನೆಯವಳಾದ-ಲಕ್ಷ್ಮಿ. ಆಕೆ\nಅಕ್ಷರಪುರುಷಳು. ಕ್ಷರ-ಅಕ್ಷರಗಳಿಗಿಂತ ಅತೀತನಾದ ಭಗವಂತ ಹದಿನೆಂಟನೆಯವನಾದ ಪುರುಷಃ. ಆತ\nಪುರುಷೋತ್ತಮ. ಗೀತೆಯಲ್ಲಿ ಇಲ್ಲಿಯ ತನಕ ಮುಖ್ಯವಾಗಿ ಭಗವಂತ ಒತ್ತುಕೊಟ್ಟು ಹೇಳಿರುವುದೇನೆಂದರೆ\n“ನನ್ನನ್ನು ಭಕ್ತಿಯಿಂದ ಭಜಿಸುವವನು ಈ ಸಂಸಾರಬಂಧದಿಂದ ಮುಕ್ತಿ ಪಡೆದು ನನ್ನನ್ನು ಸೇರುತ್ತಾನೆ” ಎಂದು.\nಇಲ್ಲಿ ನಮಗೆ ಬರುವ ಪ್ರಶ್ನೆ ಏನೆಂದರೆ-ಏಕೆ ಭಗವಂತನನ್ನು ಬಿಟ್ಟು ಹದಿನೇಳನೆಯವಳಾದ ಶ್ರೀತತ್ವವನ್ನು\nಪೂಜಿಸಬಾರದು? ತಂದೆಗಿಂತ ತಾಯಿ ಕರುಣಾಮಯಿ. ನಮ್ಮನ್ನು ಸಂಸಾರಬಂಧದಲ್ಲಿ ಹಾಕಿದ ತಾಯಿಯನ್ನು\nಪೂಜಿಸುವುದರಿಂದ ನಮಗೆ ಮೋಕ್ಷಪ್ರಾಪ್ತಿ ಸುಲಭವಾಗಬಹುದಲ್ಲವೇ? ಯಾವ ದಾರಿ ಹೆಚ್ಚು ಸೂಕ್ತ? -ಇದು\n\nಸಾಮಾನ್ಯವಾಗಿ ಎಲ್ಲರಿಗೂ ಬರುವ ಪ್ರಶ್ನೆ . ಶ್ರೀತತ್ವದ ಉಪಾಸನೆಯಿಂದ ಮುಕ್ತಿ ಸಾಧ್ಯ ಎಂದು ಸ್ತುತಿಯಲ್ಲಿ\nಹೇಳಲಾಗಿದೆ. ಉದಾಹರಣೆಗೆ ಎಲ್ಲರೂ ದೇವರ ಪೂಜೆ ಮಾಡಿ ಮಂಗಳಾರತಿ ಮಾಡುವಾಗ ಹೇಳುವ ಈ\nಕೆಳಗಿನ ಶ್ರೀಸೂಕ್ತದ ಸಾಲುಗಳು:\n\nಶ್ರಿಯೇ ಜಾತಃ ಶ್ರಿಯ ಆನಿರ್ಯಾಯಃ ಶ್ರಿಯಂ ವಯೋ ಜನಿತೃಭ್ಯೋದಧಾತು |\nಶ್ರಿಯಂ ವಸಾನಾಃ ಅಮೃತತ್ವಮಾಯನ್‌ ಭಜಂತಿ ಸದ್ಯಸ್ಸಮಿಧಾ ಮಿತದ್ಯೂನ್‌ ||\n\nಇಲ್ಲಿ ಹೇಳುವಂತೆ: \"ಶ್ರೀತತ್ವದ ಉಪಾಸನೆಗೋಸ್ಕರ ನಾವು ಹುಟ್ಟಿದ್ದೇವೆ. ಶ್ರೀತತ್ವವನ್ನು\nಸ್ತೋತ್ರಮಾಡುವವನಿಗೆ ಆಕೆ ಸಂಪತ್ತನ್ನೂ, ಧೀರ್ಫಾಯುಷ್ಯವನ್ನೂ ಕೊಡುತ್ತಾಳೆ. ಶ್ರೀತತ್ವ ಉಪಾಸನೆ\nಮಾಡಿದವರು ಅಮೃತತ್ವವನ್ನು ಪಡೆದರು. ದಂಪತಿಗಳು ಶ್ರೀತತ್ವವನ್ನು ಉಪಾಸನೆ ಮಾಡುವುದರಿಂದ ಅವರ\nಇಷ್ಟಾರ್ಥ ಸಿದ್ಧಿಯಾಗುತ್ತದೆ. ಆಕೆ ಮೋಕ್ಷಪ್ರದಳು”. ಹೀಗೆ ಹೇಳಿರುವುದರಿಂದ ಶ್ರೀತತ್ವದ ಉಪಾಸನೆಯಿಂದ\nಕೂಡಾ ಮೋಕ್ಷ ಪಡೆಯಬಹುದು ಎನ್ನುವ ಅಂಶ ಸ್ಪಷ್ಟ. ಪುರುಷೋತ್ತಮ ಭಗವಂತನ ಉಪಾಸನೆ ಮತ್ತು\nಶ್ರೀತತ್ವ ಅಥವಾ ಅಕ್ಷರ ಉಪಾಸನೆ ಇದರಲ್ಲಿ ಯಾವ ದಾರಿ ಹೆಚ್ಚು ಸೂಕ್ತ? ಇದು ಇಲ್ಲಿ ನಮ್ಮ ನಿಮ್ಮೆಲ್ಲರ ಪ್ರಶ್ನೆ.\nನಮ್ಮ ಪ್ರತಿನಿಧಿ ಅರ್ಜುನ ಈ ನಮ್ಮ ಪ್ರಶ್ನೆಯನ್ನು ಭಗವಂತನ ಮುಂದಿಡುವುದರೊಂದಿಗೆ ಈ ಅಧ್ಯಾಯ\nಆರಂಭವಾಗುತ್ತದೆ. ಎರಡನೇ ಷಟ್ಕದ ಕೊನೆಯ ಅಧ್ಯಾಯವಾದ ಇಲ್ಲಿ ಕೇವಲ ಇಪ್ಪತ್ತು ಶ್ಲೋಕಗಳಿವೆ. ಅಧ್ಯಾಯ\nಚಿಕ್ಕದಾದರೂ ಕೂಡಾ ಈ ಅಧ್ಯಾಯ ಅಪೂರ್ವ ವಿಷಯಗಳನ್ನೊಳಗೊಂಡ ಅಧ್ಯಾಯ. ಭಗವಂತ ಇಲ್ಲಿ\nಹೇಳಿರುವ ವಿಚಾರಗಳನ್ನು ನಾವು ನಮ್ಮ ಜೀವನದಲ್ಲಿ ಅಳವಡಿಸಿಕೊಂಡರೆ ನಮ್ಮ ಬದುಕು ಸಾರ್ಥಕವಾಗುತ್ತದೆ.\nಬನ್ನಿ ಈ ಅಧ್ಯಾಯದಲ್ಲಿ ಹೇಳಿರುವ ಅಪೂರ್ವ ಗುಣ-ಭಕ್ತಿ ಸಂದೇಶವನ್ನು ತಿಳಿಯೋಣ.",
  "12.5": "ಕ್ಲೇಶಃ ಅಧಿಕ ತರಃ ತೇಷಾಮ್‌ ಅವ್ಯಕ್ತ ಆಸಕ್ತ ಚೇತಸಾಮ್‌ |\nಅವ್ಯಕ್ತಾ ಹಿ ಗತಿಃ ದುಃಖಮ್‌ ದೇಹವದ್ಳಿಃ ಅವಾಪ್ಯತೇ --ಅವ್ಯಕ್ತತತ್ವದ ಉಪಾಸನೆಯನ್ನೇ ಮೆಚ್ಚುವವರಿಗೆ\nದಣಿವು ಹೆಚ್ಚು. ಅವ್ಯಕ್ತದ ಮೂಲಕ ಬಿಡುಗಡೆಯ ದಾರಿ ಸಾಧಕರಿಗೆ ಕಷ್ಟದ ಬಳಸುದಾರಿ.\n\nಶಕ್ತಿ ಉಪಾಸನೆ ಮಾಡುವವರಿಗೆ ಆಕೆ ಒಲಿದು ಮೋಕ್ಷ ಕರುಣಿಸುತ್ತಾಳೆ. ಆದರೆ ಅವ್ಯಕ್ತದ ಉಪಾಸನೆ\nಮಾಡುವವರಿಗೆ “ಅಧಿಕ ತರ ಕ್ಲ್ಷೇಶಃ: -ಉಪಾಸನೆ ತುಂಬಾ ಕಷ್ಟ. ಇದು ನೇರ ದಾರಿಯನ್ನು ಬಿಟ್ಟು\nಬಳಸುದಾರಿಯಲ್ಲಿ ಭಗವಂತನೆಡೆಗೆ ಪಯಣಿಸಿದಂತೆ. ಸಾಧಕರು ಇದನ್ನು ಬಹಳ ಕಷ್ಟದಿಂದ ಸಾಧಿಸಬೇಕು.\n\nಮುಂದಿನ ಶ್ಲೋಕಗಳಲ್ಲಿ ಕೃಷ್ಣ ನೇರ ಭಗವಂತನ ಉಪಾಸನೆ ಎಷ್ಟು ಸುಲಭ ಎನ್ನುವುದನ್ನು ವಿವರಿಸುತ್ತಾನೆ.\nಇದು ಭಗವಂತ ನಮಗೆ ತೋರಿಸಿಕೊಟ್ಟ ಸುಲಭ ಭಕ್ತಿ ಮಾರ್ಗ.",
  "12.6": "ಆದರೆ ಯಾರು ಎಲ್ಲಾ ಕರ್ಮಗಳನ್ನು ನನಗೆ ಸಮರ್ಪಿಸಿ, ನನ್ನನ್ನೇ ಪರಮ ಗತಿಯನ್ನಾಗಿ ಭಾವಿಸಿ, ಅನನ್ಯವಾದ ಯೋಗದಿಂದ ನನ್ನನ್ನು ಧ್ಯಾನಿಸುತ್ತಾ ಉಪಾಸನೆ ಮಾಡುತ್ತಾರೋ —\n\nಇದು ಸಗುಣ ಭಕ್ತಿಯ ಸ್ವರೂಪ. 'ಸರ್ವಾಣಿ ಕರ್ಮಾಣಿ ಮಯಿ ಸಂನ್ಯಸ್ಯ' — ಎಲ್ಲಾ ಕರ್ಮಗಳನ್ನು ನನಗೆ ಸಮರ್ಪಿಸುವುದು. 'ಅನನ್ಯೇನೈವ ಯೋಗೇನ' — ಅನನ್ಯ ಯೋಗದಿಂದ. 'ಮಾಂ ಧ್ಯಾಯಂತಃ' — ನನ್ನನ್ನು ಧ್ಯಾನಿಸುವುದು. ಇದು ಭಕ್ತನ ಸರ್ವೋಚ್ಚ ಸ್ಥಿತಿ.",
  "12.7": "ತೇಷಾಮ್‌ ಅಹಂ ಸಮುದ್ಧರ್ತಾ ಮೃತ್ಯು ಸಂಸಾರ ಸಾಗರಾತ್‌ ।\n\nಭವಾಮಿ ನಚಿರಾತ್‌ ಪಾರ್ಥ ಮಯ್ಯಾವೇಶಿತಚೇತಸಾಮ್‌ -ಕೆಲವರಿರುತ್ತಾರೆ: ಅವರು ಮಾಡಿದ್ದನ್ನೆಲ್ಲಾ ನನ್ನಲ್ಲಿ\n\n೧\n\nಅರ್ಪಿಸಿಬಿಡುತ್ತಾರೆ. ಅವರು ನನ್ನ ಲ್ದೇ ಬಗೆಯಿಟ್ಟವರು. ಅವರ ಸಾಧನೆಯ ಗುರಿ ನಾನಲ್ಲದೆ ಬೇರಿಲ್ಲ. ನನ್ನನ್ನೇ\n\nನೆನೆಯುತ್ತಾ ಸೇವಿಸುತ್ತಾರೆ. ಓ ಪಾರ್ಥಾ, ನನ್ನನ್ನೇ ನೆಚ್ಚಿದ ಅಂತವರನ್ನು ನಾನು ಬಹುಬೇಗ ಸಾವಿನ ಬಾಳಿನ\nಕಡಲಿನಿಂದ ಬಿಡುಗಡೆಗೊಳಿಸುತ್ತೇನೆ.\n\nಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ನನ್ನನ್ನು ಸೇರುವ ಸುಲಭ ಸಾಧನವೆಂದರೆ-ನೀನು ಜೀವನ ನಿರ್ವಹಣೆಗಾಗಿ ಯಾವ\nಕ್ರಿಯೆಯನ್ನು ಮಾಡುತ್ತೀಯೋ ಅದನ್ನು ನನ್ನಲ್ಲಿ ಅರ್ಪಿಸುವುದು” ಎಂದು. ಇಲ್ಲಿ ಕೃಷ್ಣ ಹೇಳುತ್ತಿರುವುದು ನಮ್ಮ\nಪ್ರತಿಯೊಂದು ಕ್ರಿಯೆಯ ಹಿಂದಿರಬೇಕಾದ ಅನುಸಂಧಾನವನ್ನು, ಈ ಕಾರ್ಯವನ್ನು ಭಗವಂತ ನನ್ನ ಕೈಯಿಂದ\nಮಾಡಿಸಿದ-ಇದು ಅವನಿಗರ್ಪಿತವಾಗಲಿ ಎನ್ನುವ ಅನುಸಂಧಾನ. ಈ ರೀತಿ ಇದ್ದಾಗ ನಾವು ಭಗವಂತನ\nಪೂರ್ಹಾನುಗ್ರಹಕ್ಕೆ ಪಾತ್ರರಾಗಬಹುದು. ಇಲ್ಲಿ ನಮ್ಮಲ್ಲಿರಬೇಕಾದ ಅತಿ ಮುಖ್ಯ ಅಂಶವೆಂದರೆ ಭಗವಂತನನ್ನು\nಅನನ್ಯವಾಗಿ ಏಕನಿಷ್ಠೆಯಿಂದ ಉಪಾಸನೆ ಮಾಡುವುದು. ನಮ್ಮ ಸಾಧನೆಯಲ್ಲಿ ಕೊರತೆ ಇರಬಹುದು, ಇಂದ್ರಿಯ\nನಿಗ್ರಹ. ಕಷ್ಟವಾಗಬಹುದು, ಸರ್ವಭೂತ ಹಿತಚಿಂತನೆ. ಆಗದೇ ಇರಬಹುದು, ಚಿಂತನೆಯಲ್ಲಿ\nಲೋಪದೋಷಗಳಿರಬಹುದು, ಏಕಾಗ್ರತೆ ಬಾರದೇ ಇರಬಹುದು. ಆದರೆ ಇಲ್ಲಿ ಕೃಷ್ಣನ ಭರವಸೆ ಏನೆಂದರೆ\n“ನನ್ನಲ್ಲಿ ಶರಣಾಗು, ನಿನ್ನ ಮನಸ್ಸನ್ನು ನನ್ನಲ್ಲಿ ನೆಡು-ನಾನು ನಿನ್ನನ್ನು ಉದ್ಭರಿಸುತ್ತೇನೆ” ಎನ್ನುವುದು. ನಮ್ಮ\nಚಿತ್ತದಲ್ಲಿ ಭಗವಂತನನ್ನು ನೆಲೆಗೊಳಿಸಿದಾಗ ಭಗವಂತ ನಮ್ಮನ್ನು ಈ ಹುಟ್ಟು ಸಾವಿನ ಸಂಸಾರ ಸಾಗರದಿಂದ\nಪಾರು ಮಾಡುವ ಜವಾಬ್ಧಾರಿಯನ್ನು ವಹಿಸುತ್ತಾನೆ.",
  "12.8": "ಮಯಿ ಏವ ಮನಃ ಆಧತ್ಸೃ ಮಯಿ ಬುದ್ಧಿಮ್‌ ನಿವೇಶಯ।\nನಿವಸಿಷ್ಯಸಿ ಮಯಿ ಏವ ಅತಃ ಊರ್ಧ್ವಮ್‌ ನ ಸಂಶಯಃ - ನನ್ನಲ್ಲೇ ಬಗೆಯಿಡು. ನನ್ನಲ್ಲಿ ತಿಳಿವನ್ನು ನಿಲಿಸು.\nಅದರ ಫಲವಾಗಿ ಮುಂದೆ ನನ್ನಲ್ಲೇ ನೆಲೆಸುವೆ. ಇದಕೆ ಸಂಶಯವಿಲ್ಲ.\n\nಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: ಮನಸ್ಸನ್ನು ನನ್ನಲ್ಲಿ ಆಧಾನ ಮಾಡು ಎಂದು. \"ಆಧಾನ' ಎಂದರೆ ಬೀಜ ಬಿತ್ತುವುದು ಅಥವಾ\nಕಿಡಿ ಹಚ್ಚುವುದು. ಮನಸ್ಸಿಗೆ ಭಗವಂತನ ಭಕ್ತಿಯ ಕಿಡಿಯನ್ನು ಹಚ್ಚಿ ಅದು ಪ್ರಜ್ವಲಿಸುವಂತೆ ಮಾಡಬೇಕು. ಭಕ್ತಿಯ\nಬೀಜ ಬೆಳೆಯುವಂತೆ ಪೋಷಿಸಬೇಕು. ನಿಶ್ಚಯಜ್ಞಾನ ಬುದ್ಧಿಯಲ್ಲಿ ಗಟ್ಟಿಗೊಳ್ಳಬೇಕು. ಈ ರೀತಿ ಸದಾ ಮನಸ್ಸನ್ನು\nಭಗವಂತನಲ್ಲಿ ನೆಲೆಗೊಳಿಸಿದಾಗ, ಯಾವುದೇ ಕ್ಲೇಶವಿಲ್ಲದೆ ಭಗವಂತನನ್ನು ಸೇರಬಹುದು. ಇದು ಶಕ್ತಿ\nಉಪಾಸನೆಗಿಂತ ಭಗವಂತನ ಉಪಾಸನೆ ಎಷ್ಟು ಸುಲಭ ಎನ್ನುವುದರ ವಿವರಣೆ. ಭಗವಂತನ ಉಪಾಸನೆಗೆ\nಕಟ್ಟುಪಾಡು ನಿರ್ಬಂಧ ಬಹಳ ಕಡಿಮೆ. ಉದಾಹರಣೆಗೆ ವಿಷ್ಣುಸಹಸ್ರನಾಮ ಪಾರಾಯಣ. ವಿಷ್ಣುಸಹಸ್ರನಾಮ\nಚಿಂತನೆಗೆ ಯಾವುದೇ ನಿರ್ದಿಷ್ಟ ಸಮಯದ ನಿರ್ಬಂಧವಿಲ್ಲ. ಯಾರು ಬೇಕಾದರೂ ಯಾವ ಕಾಲದಲ್ಲಿ ಕೂಡಾ\nವಿಷ್ಣುಸಹಸ್ರನಾಮ ಪಠಿಸಬಹುದು. ಸರ್ವ ರೋಗಕ್ಕೆ ಮದ್ದು ವಿಷ್ಣುಸಹಸ್ರನಾಮ. ಭಗವಂತನ ಚಿಂತನೆಯಲ್ಲಿ\nತಿಳಿಯದೇ ಆಗುವ ಲೋಪದೋಷಣಗಳಿಗೆ ಕ್ಷಮೆಯಿದೆ.\n\nನಾರಾಯಣನ ಉಪಾಸನೆ ಎಂದರೆ ಅದು ಲಕ್ಷ್ಮಿಸಮೇತ ನಾರಾಯಣನ ಉಪಾಸನೆ. ನಾರಾಯಣನನ್ನು\nಉಪಾಸನೆ ಮಾಡುವವರು ಲಕ್ಷ್ಮಿಯನ್ನು, ಇತರ ದೇವತೆಗಳನ್ನು ಪ್ರತ್ಯೇಕ ಉಪಾಸನೆ ಮಾಡುವ ಅಗತ್ಯವಿಲ್ಲ.\nಲಕ್ಷ್ಮಿಗೆ ಮತ್ತು ಸರ್ವ ದೇವತೆಗಳಿಗೆ ಅತ್ಯಂತ ಪ್ರೀತಿಪೂರ್ವಕವಾದದ್ದು-ಭಗವಂತನ ಉಪಾಸನೆ . ನಾರಾಯಣನ\nಉಪಾಸನೆ ಮಾಡುವ ಸಾಧಕನಿಗೆ ಸಕಲ ದೇವತೆಗಳು ಸಹಾಯಮಾಡಿ, ಆತ ತನ್ನ ಸಾಧನಾ ಮಾರ್ಗದಲ್ಲಿ\nಎತ್ತರಕ್ಕೇರುವಂತೆ ಮಾಡುತ್ತಾರೆ... ಇದನ್ನು ತಿಳಿದಾಗ ನಮ್ಮ ಉಪಾಸನೆಯಲ್ಲಿ ನಾವು ಸುಲಭವಾಗಿ\nಏಕಭಕ್ತಿಯನ್ನು ಸಾಧಿಸಬಹುದು. ಭಕ್ತಿ ಮಾರ್ಗದಲ್ಲಿ ಗಟ್ಟಿಗೊಳ್ಳಬಹುದು.\n",
  "12.9": "ಅಥ ಚಿತ್ತಮ್‌ ಸಮಾಧಾತುಮ್‌ ನ ಶಕ್ನೋಷಿ ಮಯಿ ಸ್ಥಿರಮ್‌।\n\nಅಭ್ಯಾಸಯೋಗೇನ ತತಃ ಮಾಮ್‌ ಇಚ್ಛಾ ಆಪ್ತುಂ ಧನಂಜಯ -ಧನಂಜಯಾ, ಒಂದೊಮ್ಮೆ ನನ್ನಲ್ಲಿ\nಒಳಬಗೆಯನ್ನು ಗಟ್ಟಿಗೊಳಿಸಲು ಸಾಧ್ಯವಾಗದಿದ್ದರೆ, ಆಗ ಮರಳಿಮರಳಿ ಅಭ್ಯಾಸದ ಬಳಕೆಯಿಂದ ನನ್ನನ್ನು\nಸೇರುವ ಬಯಕೆಯನ್ನು ಬೆಳೆಸಿಕೋ.\n\nಮನಸ್ಸಿನಲ್ಲಿ ಭಗವಂತನ ಬಗ್ಗೆ ಭಕ್ತಿ ಇದೆ, ಬುದ್ಧಿಯಲ್ಲಿ ಜ್ಞಾನಪೂರ್ಣ ಭಕ್ತಿಯ ಅಂಕುರವಿದೆ. ಆದರೂ ಕೂಡಾ\nಸ್ಥಿರವಾದ ಸ್ಮರಣೆ ಬರುತ್ತಿಲ್ಲ, ಮನಸ್ಸು ಗಟ್ಟಿಯಾಗಿ ನೆಲೆಗೊಳ್ಳುತ್ತಿಲ್ಲ ಆಗ ಏನು ಮಾಡುವುದು? ಶಾಸ್ತ್ರದಲ್ಲಿ\nಹೇಳುವಂತೆ:\n\nಸ್ಮರ್ತವ್ಯಃ ಸತತಂ ವಿಷ್ಣುಃ ವಿಸ್ಮರ್ತವ್ಯೋ ನ ಜಾತುಚಿತ್‌ |\nಸರ್ವೇ ವಿಧಿ ನಿಷೆಧಾಸ್ಸ್ಯುಹುಃ ಏತಯೋರೇವ ಕಿಂಕರಾಃ ॥\n\nಅಂದರೆ 'ನಾವು ನಿರಂತರ ಭಗವಂತನನ್ನು ನೆನಪಿನಲ್ಲಿಡಬೇಕು, ಎಂದೂ ಭಗವಂತನನ್ನು ಮರೆಯಬಾರದು\".\nಸಮಸ್ತ ವಿಧಿನಿಷೇಧ ಹೇಳುವುದು ಕೂಡಾ ಇದನ್ನೇ. ಮನಸ್ಸು ನಿರಂತರ ಭಗವಂತನಲ್ಲಿ ನಿಲ್ಲದೇ ಈ ಅಖಂಡ\nಸ್ಮರಣೆ ಸಾಧ್ಯವಿಲ್ಲ. ಇಂತಹ ಸಂದರ್ಭದಲ್ಲಿ ಏನು ಮಾಡಬೇಕು ಎನ್ನುವುದನ್ನು ಕೃಷ್ಣ ವಿವರಿಸುತ್ತಾನೆ.\n“ಮನಸ್ಸನ್ನು ಏಕಾಗ್ರತೆಯೆಡೆಗೆ ಕೊಂಡೊಯ್ಯುವ ಶಕ್ತಿ ಕೊಡು ಎಂದು ನನ್ನನ್ನು ಪ್ರಾರ್ಥಿಸು. ಅಧ್ಯಾತ್ಮದ\nದಾರಿಯಲ್ಲಿ ಏನು ಇಚ್ಛೆ ಮಾಡಿದರೂ ಅದನ್ನು ಪೂರೈಸುವ ಜವಾಬ್ಧಾರಿ ನನ್ನದು” ಎನ್ನುವ ಭರವಸೆ ಕೃಷ್ಣನದು.\nಅಭ್ಯಾಸ ಮತ್ತು ಇಚ್ಛೆ ಇದ್ದರೆ ಖಂಡಿತವಾಗಿ ಏಕಾಗ್ರತೆ ಸಾಧ್ಯ. ನಾವು ಹೇಗೆ ಮಕ್ಕಳಿಗೆ ತರಬೇತಿಕೊಟ್ಟು ಸ;\n\nಭ್ರ\n\nಅಭ್ಯಾಸ ಮಾಡಿಸಿ. ಕಲಿಸುತ್ತೇವೋ, ಹಾಗೆ ನಮ್ಮ ಮನಸ್ಸನ್ನು ರಮಿಸಿರಮಿಸಿ ಬುದ್ಧಿವಾದ ಹೇಳಿ\nಅಭ್ಯಾಸಮಾಡಿಸಬೇಕು. ಹೀಗೆ ಮಾಡಿದಾಗ ಮನಸ್ಸು ಅದನ್ನು ರೂಢಿ ಮಾಡಿಕೊಳ್ಳುತ್ತದೆ. ಮೊದಲು ನಾವು\nಲೌಕಿಕ. ಸಂಪತ್ತಿನ ಬೆನ್ನುಹತ್ತುವುದನ್ನು ಬಿಟ್ಟು, ಭಗವಂತನೆಂಬ ಅಮೂಲ್ಯ ಧನವನ್ನು ಗೆಲ್ಲುವ\n\nಧನಂಜಯರಾಗಬೇಕು.\n",
  "12.10": "ಅಭ್ಯಾಸೇ ಅಪಿ ಅಸಮರ್ಥಃ ಅಸಿ ಮತ್‌ ಕರ್ಮ ಪರಮಃ ಭವ ।\nಮತ್‌ ಅರ್ಥಮ್‌ ಅಪಿ ಕರ್ಮಾಣಿ ಕುರ್ವನ್‌ ಸಿದ್ಧಿಮ್‌ ಅವಾಪ್ಸ್ಯಸಿ ಸಿ -ಧ್ಯಾನದ ಅಭ್ಲಾ ್ಯಸವೂ ಅಸಾಧ್ಯವಾದರೆ ನನ್ನ\nಆರಾಧನಾ ರೂಪವಾದ ಕರ್ಮಗಳಲ್ಲೇ ತೊಡಗು. ಕರ್ಮವನ್ನು ನನ್ನ ಪೂಜೆಯೆಂದು... ಮಾಡಿಯೂ\n\nಸಿದ್ಧಿಪಡೆಯಬಲ್ಲೆ.\n\nಕೆಲವರಿಗೆ ಎಷ್ಟೇ ಅಭ್ಯಾಸ ಮಾಡಿದರೂ ಏಕಭಕ್ತಿ ಸಾಧ್ಯವಾಗುವುದಿಲ್ಲ. ಅಧ್ಯಾತ್ಮ ಮಾರ್ಗದ ಸಾಧನೆಯಲ್ಲಿ\nಮನಸ್ಸಿಗೆ ಒಂದು ಜನ್ಮದ ಅಭ್ಯಾಸ ಸಾಕಾಗುವುದಿಲ್ಲ. ಕೆಲವೊಮ್ಮೆ ಇಡೀ ಜನ್ಮ ಅಭ್ಯಾಸ ಮಾಡಿದರೂ\nಏಕಾಗ್ರತೆ ಬಾರದೇ ಇರಬಹುದು. ಇಂತವರಿಗೆ ಕರುಣಾಳು ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ನೀನು ಮಾಡುವ ಕರ್ಮವನ್ನು\nಸ್ವಾರ್ಥಕ್ಕಾಗಿ ಮಾಡದೆ, ಭಗವಂತನ ಪೂಜೆ ಅನ್ನುವ ಅನುಸಂಧಾನದಿಂದ ಮಾಡು” ಎಂದು. ತನ್ನ ದೈನಂದಿನ\nಪ್ರತೀ ಕರ್ಮವನ್ನು ಅರ್ಪಣಾಭಾವದಿಂದ ಭಗವಂತನ ಪೂಜೆ ಎಂದು ಮಾಡಿ, ಅಧ್ಯಾತ್ಮ ಮಾರ್ಗದಲ್ಲಿ ಸಿದ್ಧಿ\nಪಡೆಯಬಹುದು.\n",
  "12.11": "ಅಥ ಏತತ್‌ ಅಪಿ ಆಶಕ್ತಃ ಅಸಿ ಕರ್ತುಮ್‌ ಮತ್‌ ಯೋಗಮ್‌ ಆಶ್ರಿತಃ |\n\nಸರ್ವಕರ್ಮ ಫಲ ತ್ಯಾಗಮ್‌ ತತಃ ಕುರು ಯತ ಆತ್ಮವಾನ್‌ -ಇದನ್ನೂ ಮಾಡುವುದಾಗದಿದ್ದರೆ ಎಲ್ಲಾ ಬಗೆಯ\nಕರ್ಮಗಳನ್ನೂ ನನಗೆ ಅರ್ಪಿಸುವ ಸಾಧನೆ ಮಾಡು. ಅನಂತರ ಬಗೆಯನ್ನು ಬಿಗಿಗೊಳಿಸಿ ಎಲ್ಲಾ ಕರ್ಮಗಳ\nಫಲದಾಸೆಯ ನಂಟನ್ನು ತೊರೆದುಬಿಡು.\n\nಒಂದು ವೇಳೆ ಮೇಲೆ ಹೇಳಿದ ರೀತಿ ಎಲ್ಲಾ ಕರ್ಮವನ್ನು ಭಗವಂತನಿಗೆ ಅರ್ಪಿಸಲು ಸಾಧ್ಯವಾಗದೇ ಇದ್ದರೆ,\nಎಲ್ಲವನ್ನೂ ಭಗವಂತನ ಪೂಜೆಯಾಗಿ ಮಾಡಲು ಸಾಧ್ಯವಾಗದೇ ಇದ್ದರೆ, ಯಾರನ್ನಾದರೂ ಪೂಜಿಸು-ಆದರೆ\nಕೊನೆಗೆ ಸರ್ವ ಕರ್ಮವನ್ನು ಕರ್ಮಫಲದ ಬಯಕೆಯಿಲ್ಲದೆ ಭಗವಂತನಿಗೆ ಅರ್ಪಿಸು ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಇಲ್ಲಿ\nಕರ್ಮಫಲದ ತ್ಯಾಗಕ್ಕೆ ಮತ್ತು ಅರ್ಪಣೆಗೆ ಕೃಷ್ಣ ಒತ್ತು ಕೊಟ್ಟಿದ್ದಾನೆ.\n",
  "12.12": "ಶ್ರೇಯಃ ಹಿ ಜ್ಞಾನಮ್‌ ಅಭ್ಯಾಸಾತ್‌ ಜ್ಞಾನಾತ್‌ ಧ್ಯಾನಮ್‌ ವಿಶಿಷ್ಯತೇ |\n\nಧ್ಯಾನಾತ್‌ ಕರ್ಮ ಫಲ ತ್ಯಾಗಃ ತ್ಯಾಗಾತ್‌ ಶಾಂತಿಃ ಅನಂತರಮ್‌ -ಅರಿವಿಲ್ಲದ ಅಭ್ಯಾಸಕ್ಕಿಂತ ಅರಿವು ಮಿಗಿಲು.\nಬರಿದೆ ಅರಿವಿಗಿಂತ ಅರಿತು ಧ್ಯಾನಿಸುವುದು ಮಿಗಿಲು. ಬರಿದೆ ಧ್ಯಾನಕ್ಕಿಂತ ಕರ್ಮಫಲದ ನಂಟಿರದ ಧ್ಯಾನ\nಮಿಗಿಲು. ಅಂತಹ ಧ್ಯಾನದ ಮುಂದಿನ ಮಜಲೇ ಮುಕ್ತಿ.\n\nಜ್ಞಾನವಿಲ್ಲದ ಧ್ಯಾನಕ್ಕಿಂತ ಜ್ಞಾನ ಶ್ರೇಷ್ಠ. ಜ್ಞಾನ ಅಧ್ಯಾತ್ಮ ಸಾಧನೆಯಲ್ಲಿ. ಮೂಲಭೂತ\nಅವಶ್ಯಕತೆ. ಜ್ಞಾನವಿಲ್ಲದೆ ಧ್ಯಾನ ಅಥವಾ ಕರ್ಮ ಮಾಡಿ ಉಪಯೋಗವಿಲ್ಲ.\nತಿಳುವಳಿಕೆ ಇಲ್ಲದ ಶ್ರದ್ಧೆ ಅಂಧಃಶ್ರದ್ಧೆಯಾಗುತ್ತದೆ. ಹಾಗೇ ನಂಬಿಕೆ ಇಲ್ಲದ ತಿಳುವಳಿಕೆ ಅಹಂಕಾರವೆನಿಸುತ್ತದೆ.\nಆದ್ದರಿಂದ ತಿಳಿಯಬೇಕು, ತಿಳಿದು ನಂಬಬೇಕು. ಕೇವಲ ತಿಳುವಳಿಕೆ ಇದ್ದರೆ ಸಾಲದು. ಜ್ಞಾನಕ್ಕಿಂತ ಜ್ಞಾನ ಸಹಿತ\nಧ್ಯಾನ ಮೇಲು. ಎಲ್ಲಕ್ಕಿಂತ ಹಿರಿದು ಕರ್ಮಫಲ ತ್ಯಾಗ. ಆದ್ದರಿಂದ ಮೊದಲು ತಿಳಿದುಕೋ, ತಿಳಿದು ಅಭ್ಯಾಸ\nಮಾಡು. ಆದರೆ ನಿನ್ನ ಧ್ಯಾನ ಕರ್ಮಫಲವಿಲ್ಲದ ಧ್ಯಾನವಾಗಿರಲಿ. ಈ ರೀತಿಯ ಜೀವನ ಶೈಲಿಯಿಂದ\nಮೋಶ್ಷಪ್ರಾಪ್ತಿ ಸಾಧ್ಯ.\n\nಇಲ್ಲಿಯ ತನಕ ಭಗವಂತನ ಉಪಾಸನೆ ಹೇಗಿರಬೇಕು ಎನ್ನುವುದನ್ನು ವಿವರಿಸಿದ ಕೃಷ್ಣ, ಮುಂದೆ ನಾವು ದೇವರು\nಮೆಚ್ಚುವ ಬದುಕನ್ನು ಬದುಕಬೇಕಾದರೆ ಯಾವ ರೀತಿ ನಮ್ಮ ಬದುಕನ್ನು ರೂಪಿಸಿಕೊಳ್ಳಬೇಕು, ನಮ್ಮ\n\nಜೀವನಕ್ರಮ ಮತ್ತು ಅನುಷ್ಠಾನ ಹೇಗಿರಬೇಕು ಎನ್ನುವುದನ್ನು ವಿವರಿಸುತ್ತಾನೆ.",
  "12.13": "ಅದ್ವೇಷ್ಟಾ ಸರ್ವಭೂತಾನಾಮ್‌ ಮೈತ್ರಃ ಕರುಣಃ ಏವ ಚ |\nನಿರ್ಮಮಃ ನಿರಹಂಕಾರಃ ಸಮದುಃಖಸುಖಃ ಕ್ಷಮೀ -- ಯಾವ ಜೀವಿಗಳಲ್ಲು ಹಗೆಯಿರದವನು, ಎಲ್ಲರ ನೇಹಿಗನು, ದುಃಖವನ್ನು ಕಂಡು ಕರಗುವವನು, ನಾನು-ನನ್ನದು ಎಂಬ ಹಮ್ಮಿರದವನು, ಸುಖದಲ್ಲಿ ಹಿಗ್ಗದವನು, ದುಃಖದಲ್ಲಿ ಕುಗ್ಗದವನು, ತಾಳ್ಮೆ ತಪ್ಪದವನು,\n\nಗೀತೆಯಲ್ಲಿ ಭಗವಂತನಿಗೆ ಅತ್ಯಂತ ಪ್ರಿಯರಾದ ಭಕ್ತರ ಲಕ್ಷಣಗಳನ್ನು ವಿವರಿಸುವ ಸರಣಿ ಇಲ್ಲಿಂದ ಆರಂಭವಾಗುತ್ತದೆ. 'ಅದ್ವೇಷ್ಟಾ' — ಯಾರನ್ನೂ ದ್ವೇಷಿಸದಿರುವುದು. 'ಮೈತ್ರಃ ಕರುಣಃ' — ಸ್ನೇಹಶೀಲತೆ ಮತ್ತು ಕರುಣೆ. 'ನಿರ್ಮಮಃ ನಿರಹಂಕಾರಃ' — ಮಮತೆ ಮತ್ತು ಅಹಂಕಾರದಿಂದ ಮುಕ್ತನಾಗಿರುವುದು.",
  "12.14": "ಸಂತುಷ್ಟಃ ಸತತಮ್‌ ಯೋಗೀ ಯತಾತ್ಮಾ ದೃಢನಿಶ್ಚಯಃ |\nಮಯಿ ಅರ್ಪಿತ ಮನಃ ಬುದ್ಧಿಃ ಯಃ ಮತ್‌ ಭಕ್ತಃ ಸಃ ಮೇ ಪ್ರಿಯಃ -- ಯಾವಾಗಲೂ ತೃಪ್ತಿಯಿಂದಿರುವವನು, ಧ್ಯಾನಸಾಧನೆಯಲ್ಲಿ ತೊಡಗಿದವನು, ಬಗೆ ಬಿಗಿ ಹಿಡಿದವನು, ತತ್ವದ ನಿರ್ಧಾರದಿಂದ ಬಗೆ ಗಟ್ಟಿಗೊಂಡವನು, ಬಗೆ-ತಿಳಿವುಗಳನ್ನು ನನ್ನಲ್ಲಿ ಅರ್ಪಿಸಿದವನು- ಇಂತಹ ನನ್ನ ಭಕ್ತ ನನಗೆ ಅಚ್ಚುಮೆಚ್ಚು.\n\nಭಗವಂತ ಮೆಚ್ಚುವ ಮಾನವ ವರ್ತನೆಯ ಬಗ್ಗೆ ಕೃಷ್ಣ ವಿವರಿಸುತ್ತಾ ಮೊದಲನೆಯದಾಗಿ ಹೇಳುತ್ತಾನೆ: “ಅದ್ವೇಷ್ಟಾ\nಸರ್ವಭೂತಾನಾಂ”ಎಂದು. ಅಂದರೆ ಯಾರನ್ನೂ ದ್ವೇಷಿಸದಿರುವುದು. ಇದು ಭಗವದ್ಭಕ್ತನಲ್ಲಿ ಇರಬೇಕಾದ\nಮೊದಲನೇ ಗುಣ. ದ್ವೇಷದಲ್ಲಿ ಎರಡು ವಿಧ. ಒಂದು ಒಳ್ಳೆಯವರನ್ನು(ಅವರ ಉದ್ಧಾರವನ್ನು ಕಂಡು)\nದ್ವೇಷಿಸುವುದು; ಇನ್ನೊಂದು ಕೆಟ್ಟವರನ್ನು(ಅವರ ಕೆಟ್ಟತನವನ್ನು ಕಂಡು) ದ್ವೇಷಿಸುವುದು. ದ್ವೇಷ ಬರುವುದು\nಅಸಹನೆ ಮತ್ತು ಹೊಟ್ಟೆಕಿಚ್ಚಿನಿಂದಾಗಿ. ಇನ್ನೊಬ್ಬರ ಉತ್ಕರ್ಷವನ್ನು ಕಂಡು ಸಂಕಟಪಡುವುದು ದ್ವೇಷ.\nಒಳ್ಳೆಯವನಿರಲಿ, ಕೆಟ್ಟವನಿರಲಿ-ಹೊಟ್ಟೆಕಿಚ್ಚು ಅಸಹನೆ ಬೇಡ. ಎಲ್ಲಿ ಒಳ್ಳೆಯತನವಿದೆ ಅದನ್ನು ಪ್ರೀತಿಸು, ಸ್ನೇಹ\nಬೆಳೆಸು. ದುಷ್ಟರನ್ನು ದೂರ ಬಿಟ್ಟುಬಿಡು; ಒಳ್ಳೆಯತನವನ್ನು, ಒಳ್ಳೆಯವರನ್ನು ಪ್ರೀತಿಸು. ಇನ್ನೊಬ್ಬರ ಕಷ್ಟವನ್ನು\nಕಂಡು ಕರಗು. ನಾನು, ನನ್ನದು ,ನನ್ನಿಂದ ಎನ್ನುವ ಅಹಂಕಾರ ಮಮಕಾರವನ್ನು ಬಿಟ್ಟುಬಿಡು. \"ಈಶಾವಾಸ್ಯಂ\nಇದಮ್‌ ಸರ್ವಂ' -ಎಲ್ಲವುದರ ಒಡೆಯ ಆ ಭಗವಂತ. ಆತ ಕೊಟ್ಟಿರುವುದರಿಂದ ಇದೆ ಎನ್ನುವ ಮನೋಭಾವ\nಇರಲಿ... ಹೇಗೆ. ಅಹಂಕಾರ ಒಳ್ಳೆಯದಲ್ಲವೋ ಹಾಗೇ ಅತಿಯಾದ ಮಮಕಾರ ಒಳ್ಳೆಯದಲ್ಲ.\nಪುರಂದರದಾಸರಂತೆ ಪ್ರೀತಿಯಲ್ಲಿ ನಿರ್ಲಿಪ್ರತೆ ಇರಲಿ. ಪುರಂದರದಾಸರಿಗೆ ಒಬ್ಬ\nಮಗನಿದ್ದ. ಅವರು ಆತನನ್ನು ಪ್ರೀತಿಯಿಂದ ನೋಡಿಕೊಳ್ಳುತ್ತಿದ್ದರು. ಒಂದು ದಿನ ಪ್ರೀತಿಯ ಮಗ ಸತ್ತು ಹೋದ.\nಆಗ ಅವರು “ಗಿಳಿಯು ಪಂಜರದೊಳಿಲ್ಲ-ನೀನು ಕೊಟ್ಟ ಗಿಳಿ ನಿನ್ನನ್ನು ಸೇರಿತು” ಎಂದು ನಿರ್ಲಿಪ್ತರಾಗಿ\nಬದುಕಿದರು. ನಾವು ದುಃಖ-ಸುಖವನ್ನು ಕಾಣುವುದರಲ್ಲಿ. ಸಮತೋಲನ ಸಾಧಿಸಬೇಕು. ಸುಖ ಬಂದಾಗ\nಹಾರಾಟ ಬೇಡ. ದುಃಖ ಬಂದಾಗ ಕುಸಿಯದೆ ಬಂದದ್ದನ್ನು ಎದುರಿಸಬೇಕು. ಇನ್ನೊ ಬ್ಬರ ಮೇಲೆ ಕ್ಷಮಾ ಭಾವನೆ\nಇರಲಿ. ಪ್ರತೀಕಾರ ಬೇಡ. [ತಪ್ಪು ಮಾಡಿದವರನ್ನು ನ್ಯಾಯಾಧೀಶರು, ಅಧಿಕಾರಿಗಳು ದಂಡಿಸಬಹುದು. ಅದು\n\nಅವರ ಕರ್ತವ್ಯಧರ್ಮ-ಅಲ್ಲಿ ಪ್ರತೀಕಾರವಿಲ್ಲ].\n\nಮುಂದುವರಿದು ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಸಂತುಷ್ಠಃ ಸತತಂ ಯೋಗೀ ಯತಾತ್ಮಾ ದೃಢನಿಶ್ಚಯಃ” ಎಂದು.\nಯಾವುದೇ ಒಬ್ಬ ಮನುಷ್ಯ ಹಾಯಾಗಿರಬೇಕಾದರೆ ಇರಬೇಕಾದ ಚಿತ್ತವೃತ್ತಿ 'ಅತೃಪ್ಪಿ ಇಲ್ಲದೆ ಇರುವುದು”.\nಜೀವನದಲ್ಲಿ ನಮ್ಮೆಲ್ಲಾ ದುಃಖಗಳಿಗೆ ಕಾರಣ ಅತೃಪ್ತಿ. ಇಲ್ಲದೇ ಇರುವುದರ ಬಗೆಗೆ ಅತೃಪ್ಪಿ ಪಡುವುದರ ಬದಲು\nಇರುವುದರ ಬಗ್ಗೆ ತೃಪ್ತಿ ಪಡು. ಏನಿದೆಯೋ ಅದರಲ್ಲಿ ತೃಪ್ತಿ ಪಡುವುದನ್ನು ಅಭ್ಯಾಸ ಮಾಡು. ಸದಾ\nಯೋಗಿಯಾಗು. ಇಲ್ಲಿ ಯೋಗಿ ಅನ್ನು ವುದಕ್ಕೆ ಅನೇಕ ಅರ್ಥಗಳಿವೆ. ವಿವಿಧ ಆಸನಗಳ ಅಭ್ಯಾಸ ಯೋಗವಲ್ಲ.\nಮನಸ್ಸನ್ನು ಏಕಾಗ್ರಗೊಳಿಸಲು ಮಾಡಬೇಕಾದ ಪ್ರಕ್ರಿಯೆ ಯೋಗ. ಕೋತಿಯಂತೆ ಹರಿದಾಡುವ ನಮ್ಮ\nಮನಸ್ಸನ್ನು ಹಿಡಿದು ನಿಲ್ಲಿಸುವುದು-ಗಾಳಿಯನ್ನು ಹಿಡಿದು ನಿಲ್ಲಿಸಿದಂತೆ. ಅದು ತುಂಬಾ ವಿಚಿತ್ರ. ಮನಸ್ಸು ಜಾರಿ\nಹೋಗುವುದು ನಮಗೆ ತಿಳಿಯುವುದು ಅದು ಹೋದ ಮೇಲೆ. ಇಂತಹ ಮನಸ್ಸನ್ನು ಹಿಡಿದು ನಿಲ್ಲಿಸಲು ಮೊದಲು\nಬೆನ್ನುಹುರಿಯನ್ನು ನೆಟ್ಟಗೆ ಮಾಡಿ ಸ್ಥಿರವಾಗಿ ಕುಳಿತುಕೊಳ್ಳಲು ಅಭ್ಯಾಸ ಮಾಡುವುದು-ಆಸನ(ಯಾವ\nಆಸನವಾದರೂ ಸರಿ). ನಂತರ ಪ್ರಾಣಾಯಾಮದ ಮೂಲಕ ಒಳಗಿನ ಚಿಂತನೆಯನ್ನು ಜಾಗೃತಗೊಳಿಸುವುದು\nಯೋಗ. ಸ್ವಚ್ಛ ಮನಸ್ಸಿನಲ್ಲಿ ಭಗವಂತನನ್ನು ಕೂರಿಸುವುದು ಯೋಗ, ಬದುಕಿನಲ್ಲಿ ಜೀವನ ನಿರ್ವಹಣೆಗೆ\nಕಂಡುಕೊಂಡ(ಸಿಕ್ಕಿದ) ದಾರಿಯನ್ನು ಶ್ರದ್ಧೆಯಿಂದ ಪ್ರಾಮಾಣಿಕವಾಗಿ ಮಾಡುವುದು ಯೋಗ. ಈ ರೀತಿ\nಅಭ್ಯಾಸದಿಂದ ಮನಸ್ಸನ್ನು ನಮ್ಮ ಹಿಡಿತದಲ್ಲಿಟ್ಟುಕೊಳ್ಳಬೇಕು. ಏನನ್ನೂ ಕೆಟ್ಟ ಭಾವದಿಂದ ಕಾಣದೇ ಇರವುದನ್ನು\nಅಭ್ಯಸಿಸು. ಅಧ್ಯಾತ್ಮ ದಾರಿಯಲ್ಲಿ ಅಚಲವಾದ ನಿರ್ಧಾರವಿರಲಿ. ಏನೇ ಬರಲಿ ದೃಢನಿಶ್ಚ ಯದಿಂದ ಮುಂದೆ\nಸಾಗು. ಮನಸ್ಸು ಭಗವಂತನಿಗಾಗಿ ಹಾತೊರೆಯಲಿ. ಬುದ್ಧಿ ಭಗವಂತನನ್ನು ಅರಿಯಲಿ. “ಈ ರೀತಿ ಯಾರು\n\nನನ್ನನ್ನು ಪ್ರೀತಿಸುತ್ತಾರೋ(ಭಕ್ತ) ಅವರು ನನಗೆ ಅತೀ ಪ್ರಿಯ” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.\n",
  "12.15": "ಯಸ್ಮಾತ್‌ ನ ಉದ್ವಿಜತೇ ಲೋಕಃ ಲೋಕಾತಶ್‌ ನ ಉದ್ವಿಜತೇಚಯಃ |\n\nಹರ್ಷ ಅಮರ್ಷ ಭಯ ಉದ್ವೇಗೈಃ ಮುಕ್ತಃ ಯಃ ಸಃ ಚ ಮೇ ಪ್ರಿಯಃ -ಯಾರಿಂದಲೂ ನೋಯದವನು,\nಯಾರನ್ನೂ ನೋಯಿಸದವನು, ಹಮ್ಮಿನಿಂದ ಕೇಡಿಗೆಳೆಸದವನು, ರೇಗದವನು, ಅಂಜದವನು,\nತಲ್ಲಣಗೊಳ್ಳದವನು-ಅವನು ನನಗೆ ಅಚ್ಚುಮೆಚ್ಚು.\n\nನಮ್ಮನ್ನು ನೋಡಿ ಇನ್ನೊಬ್ಬರು ಉದ್ವೇಗಗೊಳ್ಳಬಾರದು.. ಹಾಗೂ ನಾವು ಇನ್ನೊಬ್ಬರನ್ನು\nಉದ್ವೇಗಗೊಳಿಸಬಾರದು. ಯಾರೂ ನಮ್ಮನ್ನು ನೋಡಿ ಅಸಹನೆ-ಅತೃಪ್ತಿ ತಾಳಬಾರದು ಮತ್ತು ಇನ್ನೊಬ್ಬರನ್ನು\nನೋಡಿ ನಾವು ಅಸಹನೆ ತಾಳಬಾರದು. ನಾವು ಪ್ರಪಂಚವನ್ನು ಬೇಷರತ್ತಾಗಿ ಪ್ರೀತಿಸಿದಾಗ ಇದನ್ನು ಸಾಧಿಸಲು\nಸಾಧ್ಯ. ಭಗವಂತ ಮೆಚ್ಚುವ ಕೆಲಸ ಮಾಡಿದಾಗ ಭಗವಂತ ನಮ್ಮನ್ನು ಪ್ರೀತಿಸುತ್ತಾನೆ. ಭಗವಂತ\n\nಪ್ರೀತಿಸುವವರನ್ನು ಇಡೀ ಪ್ರಪಂಚವೇ ಪ್ರೀತಿಸುತ್ತದೆ.\n\nನಾವು ಹರ್ಷ ಅಮರ್ಷ ಭಯ ಮತ್ತು ಉದ್ವೇಗದಿಂದ ಮುಕ್ತರಾಗಬೇಕು. ಮಾಡಬಾರದ್ದನ್ನು ಮಾಡುವುದರಲ್ಲಿ\nಹಿಗ್ಗು ಹರ್ಷ; ಇನ್ನೊಬ್ಬರು ಮಾಡಬೇಕಾದ್ದನ್ನು ಮಾಡಿದಾಗ ಅದನ್ನು ನೋಡಿ ಹೊಟ್ಟೆಕಿಚ್ಚು ಪಡುವುದು ಅಮರ್ಷ.\nಸಾಧಕ ಹರ್ಷ ಅಮರ್ಷದಿಂದ ಮುಕ್ತನಾಗಿರಬೇಕು. ಹೆದರುವಂತಹ ಕೆಲಸ ಮಾಡಬೇಡ ಮತ್ತು ತಪ್ಪು\nಮಾಡದಿದ್ದಾಗ ಭಯಬೇಡ. ಇನ್ನೊಬ್ಬರನ್ನು ನಾವು ಸಂಶಯ ದೃಷ್ಟಿಯಿಂದ ನೋಡಿದರೆ ಅವರೂ ನಮ್ಮನ್ನು\nಸಂಶಯ ದೃಷ್ಟಿಯಿಂದ ನೋಡುತ್ತಾರೆ. ನಾವು ಇನ್ನೊಬ್ಬರನ್ನು ನಂಬದಿದ್ದಾಗ ಅವರೂ ನಮ್ಮನ್ನು ನಂಬುವುದಿಲ್ಲ.\nಇದರಿಂದ ಉದ್ವೇಗ(Tension). ಉದ್ವೇಗದಿಂದ ಅನೇಕ ವಿಧದ ರೋಗಗಳು ನಮ್ಮ ದೇಹದಲ್ಲಿ ಮನೆ\nಮಾಡುತ್ತವೆ. ನಾವು ಭಗವಂತನನ್ನು ನಂಬಿ ನಿಸ್ವಾರ್ಥವಾಗಿ, ನಿಶ್ಚಿಂತೆಯಿಂದ ಬದುಕಲು ಕಲಿಯಬೇಕು.\n“ಜೀವನದಲ್ಲಿ ಎಲ್ಲರನ್ನು ಪ್ರೀತಿಸುವ ಸಾಧಕ; ಹರ್ಷ ಅಮರ್ಷ ಭಯ ಮತ್ತು ಉದ್ವೇಗವನ್ನು ಗೆದ್ದ ಸಾಧಕ ನನಗೆ\nಪ್ರಿಯ” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.\n",
  "12.16": "ಅನಪೇಕ್ಷಃ ಶುಚಿಃ ದಕ್ಷಃ ಉದಾಸೀನಃ ಗತವ್ಯಥಃ ।\n\nಸರ್ವಾರಂಭಪರಿತ್ಯಾಗೀ ಯಃ ಮತ್‌ ಭಕ್ತಃ ಸಃ ಮೇ ಪ್ರಿಯಃ -ಏನನ್ನೂ ಬಯಸದವನು, ಚೊಕ್ಕವಾಗಿ\nಚುರುಕಾಗಿರುವವನು, ಯಾವುದನ್ನೂ ಹಚ್ಚಿಕೊಳ್ಳದವನು, ಕಂಗೆಡದವನು, ಭಗವಂತನ ಆರಾಧನೆಯಲ್ಲದ\nಯಾವ ತೊಡಗುವಿಕೆಯಲ್ಲೂ ತೊಡಗದವನು,[ಎಲ್ಲವನ್ನೂ ಭಗವಂತನಿಗೆ ಅರ್ಪಿಸಿ ನಾನು-ನನ್ನದು ಎಂಬ\nಹಮ್ಮು ತೊರೆದವನು], ಇಂತಹ ನನ್ನ ಭಕ್ತ ನನಗೆ ಅಚ್ಚುಮೆಚ್ಚು.\n\nತನ್ನ ಭಕ್ತನಲ್ಲಿರಬೇಕಾದ, ಭಕ್ತಿಗೆ ಪೂರಕವಾದ ಆರು ಗುಣಗಳನ್ನು ಕೃಷ್ಣ ಈ ಶ್ಲೋಕದಲ್ಲಿ ವಿವರಿಸಿದ್ದಾನೆ.\n\n(೧) ಅನಪೇಕ್ಷಃ : ಅದು ಬೇಕು ಇದು ಬೇಕು ಎಂದು ಬಯಸದೇ ಇರುವುದು. ಯಾವುದರಿಂದ ತಾತ್ಕಾಲಿಕ ಸುಖ\nಬರುತ್ತದೋ ಅದರ ಹಿಂದೆ ಹೋಗದೆ, ಶಾಶ್ವತವಾದ ಮೋಕ್ಷ ಮಾರ್ಗದಲ್ಲಿ ನಡೆಯುವುದು. ಏನು ಸಿಕ್ಕಿತೋ\nಅದರಲ್ಲಿ ಸಂತೋಷಪಡುವುದು-ಇದು ಅನಪೇಕ್ಷಃ.\n\n(೨) ಶುಚಿಃ : ನಿರ್ಮಲ ಮತ್ತು ನಿರಾಳವಾಗಿರುವುದು. ಇದೇ ಮಡಿ. ಬಾಯಲ್ಲಿ ಕೆಟ್ಟ ಮಾತು, ಮನಸ್ಸಿನಲ್ಲಿ ಕೆಟ್ಟ\nಯೋಚನೆ, ಮೈಯಲ್ಲಿ ಕೊಳೆ-ಇದು ಮೈಲಿಗೆ. ಮೊದಲು ನಾವು ನಮ್ಮ ಮನಸ್ಸಿನ ಕೊಳೆ ತೊಳೆದುಕೊಳ್ಳಬೇಕು.\nಇದಕ್ಕೆ ಪೂರಕವಾಗಿ ಬಾಹ್ಯ ಶುದ್ಧಿ. ಇದಕ್ಕಾಗಿ ಶಾಂತಿ ಪಾಠದಲ್ಲಿ ಹೀಗೆ ಹೇಳುತ್ತೇವೆ: “ಓಂ ಭದ್ರಂ ಕರ್ಣೇಭಿಃ\nಶೃಣುಯಾಮ ದೇವಾಃ ಭದ್ರಂ ಪಶ್ಯೇಮಾಕ್ಷಭಿರ್ಯಜತ್ರಾಃ ಎಂದು. ನಾವು ಒಳ್ಳೆಯದನ್ನು ನೋಡೋಣ,\nಒಳ್ಳೆಯದನ್ನು ಮಾತನಾಡೋಣ, ಒಳ್ಳೆಯದನ್ನು ಯೋಚಿಸೋಣ ಎಂದು. ಇದು ನಿಜವಾದ ಮಡಿ.\n\nಮಡಿಯ ಬಗ್ಗೆ ಹೆಚ್ಚು ಪ್ರಸಿದ್ಧವಾದ ಎರಡು ಶ್ಲೋಕಗಳಿವೆ:\n\nಅಪವಿತ್ರಃ ಪವಿತ್ರೋವ ಸರ್ವಾವಸ್ಥಾಂ ಗತೋಪಿವಾ |\nಯಃ ಸ್ಮರೇತ್‌ ಪುಂಡರೀಕಾಕ್ಷಂ ಸ ಬಾಹ್ಯಾಭ್ಯಂತರಃ ಶುಚಿಃ ॥\n\nಮತ್ತು\nಅತಿನೀಲಘನಶ್ಯಾಮಂ ನಲಿನಾಯತಲೋಚನಂ |\nಸ್ಮರಾಮಿ ಪುಂಡರೀಕಾಕ್ಷಂ ತೇನ ಸ್ನಾ ತೋ ಭಾವಾಮ್ಯಹಂ॥\nಇಲ್ಲಿ ಪುಂಡರೀಕಾಕ್ಷನನ್ನು ಸ್ಮರಣೆ ಮಾಡಬೇಕು ಎಂದು ಹೇಳಿದ್ದಾರೆ. ಇದೊಂದು ಭಗವಂತನ ವಿಶೇಷ ನಾಮ.\nಪುಂಡರೀಕಾಕ್ಷ ಎಂದರೆ ಕೆಂದಾವರೆಯಂತಹ ಕಣ್ಣುಳ್ಳವನು ಎಂದರ್ಥ. ಭಗವಂತನ ಕಣ್ಣು ಯಾವಾಗಲೂ\nಕೆಂದಾವರೆ ಎಸಳಿನಂತೆ ಅರಳಿ ನಳನಳಿಸುತ್ತಿರುತ್ತದೆ. ಸಾಮಾನ್ಯವಾಗಿ ನಮಗೆ ಅತ್ಯಂತ ಸಂತೋಷವಾದಾಗ\nನಮ್ಮ ಕಣ್ಣು ಅರಳುತ್ತವೆ. ಆದರೆ ಭಗವಂತ ಸದಾ ಸಂತೋಷದ ಬುಗ್ಗೆ. ಭಗವಂತ ಪ್ರೀತಿಯಿಂದ ಕಣ್ಣರಳಿಸಿ\nನನ್ನನ್ನು ನೋಡುತ್ತಿದ್ದಾನೆ. ಅವನ ಕಣ್ಣಿನಿಂದ ಹರಿದುಬರುತ್ತಿರುವ ಅನುಗ್ರಹದ ರಸಧಾರೆಯಲ್ಲಿ ನಾನು\nಮೀಯುತ್ತಿದ್ದೇನೆ. ಅವನ ಅನುಗ್ರಹದ ಕೃಪಾದೃಷ್ಟಿ ನನ್ನ ಮೇಲೆ ಹರಿದಿದೆ. ನಾನು ಅದರಲ್ಲಿ ಮಿಂದೆ ಎನ್ನುವ\nಅನುಸಂಧಾನ ಶುಚಿ. ಹೀಗೆ ನಾವು ಭಗವಂತನ ಅನುಗ್ರಹದಿಂದ ಒಳಗೂ ಹೊರಗೂ ಮಡಿಯಾಗಬೇಕು.\n(೩) ದಕ್ಷಃ : ನಮ್ಮಲ್ಲಿ ಮನಸ್ಸನ್ನು ಭಗವಂತನೆಡೆಗೆ ಹರಿಸುವ ದಕ್ಷತೆ ಇರಬೇಕು. ಆತ ನಮ್ಮ ಬಾಹ್ಯ ಪ್ರಯತ್ನಕ್ಕೆ\nಒಲಿಯಲಾರ. ನಾವು ಅಂತರಂಗದಿಂದ ಆತನೆಡೆಗೆ ಹೋಗಬೇಕು. ಬಾಹ್ಯ ಕ್ರಿಯೆ ನಮ್ಮ ಅಂತರಂಗದ ಸಾಧನೆಗೆ\nಪೂರಕ ಅಷ್ಟೆ. ಭಗವಂತನನ್ನು ಹೇಗೆ ಸೇರಬಹುದು ಎನ್ನುವ ತಿಳುವಳಿಕೆ, ಜಾಣತನ ನಮ್ಮಲ್ಲಿರಬೇಕು.\n(೪) ಉದಾಸೀನ : ಅಂತರ್ಯಾಮಿಯಾಗಿರುವುದು. ಯಾವುದೇ ಬಾಹ್ಯ ಕ್ರಿಯೆಗೆ ಒತ್ತು ಬೇಡ, ಆಗ್ರಹ ಬೇಡ.\nಉದಾಹರಣೆಗೆ- ನಿಮ್ಮ ಕುಟುಂಬದಲ್ಲಿ ಯಾರೋ ಒಬ್ಬರು ತಮ್ಮ ಯಾವುದೋ ಒಂದು ಫಲಾಪೇಕ್ಷೆಯನ್ನು\nಈಡೇರಿಸಿಕೊಳ್ಳಲು ಯಾವುದೋ ಒಂದು ಪೂಜೆ ಮಾಡಿಸುತ್ತಿದ್ದಾರೆ. ಅಂಥಹ ಸಂದರ್ಭದಲ್ಲಿ ಫಲಾಪೇಕ್ಷೆಯಿಂದ\nಭಗವದಾರಾಧನೆ ತಪ್ಪು ಎಂದು ಅದನ್ನು ವಿರೋಧಿಸಿ ನಿಲ್ಲುವುದು ಒಳ್ಳೆಯದಲ್ಲ. ಏನೇ ಇರಲಿ ಅದು ಭಗವಂತನ\nಸೇವೆ; ಅದು ಭಗವಂತನನ್ನು ಸೇರಲಿ ಎಂದು ಪ್ರಾರ್ಥಿಸಿ. ಎಲ್ಲರೊಂದಿಗಿದ್ದು ಯಾವುದೇ ಆಗ್ರಹವಿಲ್ಲದೆ ಬದುಕಲು\nಕಲಿಯಿರಿ.\n(೫) ಗತವ್ಯಥಃ : ಏನೇ ಆದರೂ ಬೇಸರಿಸಿಕೊಳ್ಳದೆ ಸದಾ ಆನಂದವಾಗಿರುವುದು.\n(೬) ಸರ್ವಾರಂಭಪರಿತ್ಯಾಗಿ : ಭಗವಂತನ ಪಾರಮ್ಯಕ್ಕೆ ವಿರುದ್ಧವಾದ ಯಾವ ಆರಂಭಕ್ಕೂ ತೊಡಗದಿರುವುದು.\nಎಲ್ಲಾ ಆರಂಭವನ್ನು ಫಲಕಾಮನೆಯಿಂದ ಮಾಡುವುದನ್ನು ಬಿಡು. ಎಲ್ಲವನ್ನೂ ಕೊನೆಗೆ ಕೃಷ್ಣಾರ್ಪಣಮಸ್ತು\nಎಂದು ಭಗವಂತನಲ್ಲಿ ಅರ್ಪಿಸು.\n“ಯಾರು ಈ ಗುಣಗಳೊಂದಿಗೆ ನನ್ನನ್ನು ಪ್ರೀತಿಸುತ್ತಾರೋ ಅಂತಹ ಭಕ್ತ ನನಗೆ ಅಚ್ಚುಮೆಚ್ಚು ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.",
  "12.17": "ಯಃ ನ ಹೃಷ್ಯತಿ ನ ದ್ವೇಷ್ಟಿ ನ ಶೋಚತಿ ನ ಕಾಂಕ್ಷತಿ |\nಶುಭ ಅಶುಭ ಪರಿತ್ಯಾಗೀ ಭಕ್ತಿಮಾನ್‌ ಯಃ ಸಃ ಮೇ ಪ್ರಿಯಃ -ಬೀಗುವುದಿಲ್ಲ; ಹೇಸುವುದಿಲ್ಲ; ಕೊರಗುವುದಿಲ್ಲ;\nಬಯಸುವುದಿಲ್ಲ. ಒಳಿತು ಕೆಡುಕುಗಳ ಕುರಿತು ಕಾಳಜಿಯಿಲ್ಲ, ಇಂತಹ ಭಕ್ತನು ನನಗೆ ಅಚ್ಚುಮೆಚ್ಚು.\n\nಇಲ್ಲಿ ಹಿಂದೆ ಹೇಳಿದ ಕೆಲವು ವಿಚಾರ ಪುನರುಕ್ತಿಯಾಗಿದೆ. ಸಾಮಾನ್ಯವಾಗಿ ಒಂದು ವಿಷಯವನ್ನು ಹೆಚ್ಚು\nಸ್ಪಷ್ಟಪಡಿಸುವುದಕ್ಕಾಗಿ ಮತ್ತು ಒಂದು ವಿಚಾರಕ್ಕೆ ಹೆಚ್ಚು ಒತ್ತು ಕೊಡುವುದಕ್ಕಾಗಿ ಪುನರುಕ್ತಿ. ಇಲ್ಲಿ ಕೃಷ್ಣ\nಹೇಳುತ್ತಾನೆ: ಯಾವುದೋ ಒಂದು ಒಳ್ಳೆಯ ಕೆಲಸ ಮಾಡಿದಾಗ ಬೀಗಬೇಡ ಮತ್ತು ಇನ್ನೊಬ್ಬರನ್ನು ಕಂಡು\nಹೇಸಿಗೆ ಪಡಬೇಡ. ಸಿಕ್ಕಿತೆಂದು ಅತೀವ ಖುಶಿ, ಸಿಗಲಿಲ್ಲವೆಂದು ದುಃಖ ಅಥವಾ ದ್ವೇಷ ಬೇಡ. ಜೀವನದಲ್ಲಿ ಜ್ಞಾನ\nಭಕ್ತಿ ವೈರಾಗ್ಯ ಇದು ಶುಭ. ಉಳಿದ ಎಲ್ಲಾ ವಿಷಯಗಳ ಒಳಿತು ಕೆಡುಕುಗಳ ವಿಶ್ಲೇಷಣೆ ಬೇಡ. ಈ ಪ್ರಪಂಚದಲ್ಲಿ\nಯಾವುದೂ ಆಕಸ್ಮಿಕವಲ್ಲ. ಇಲ್ಲಿ ನಡೆಯುವ ಪ್ರತಿಯೊಂದು ಘಟನೆ ಹಿಂದೆ ನಮಗೆ ತಿಳಿಯದೇ ಇರುವ ಒಂದು\nಕಾರಣವಿರುತ್ತದೆ. ಅದಕ್ಕಾಗಿ ಅದನ್ನು ಶುಭ-ಅಶುಭ ಎಂದು ನಿರ್ಧರಿಸಲು ಸಾವು ಸಮರ್ಥರಲ್ಲ. ಈ ರೀತಿ ತಿಳಿದು\n\nಬದುಕುವ ಭಕ್ತ ನನಗೆ ಪ್ರಿಯ ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.",
  "12.18": "ಸಮಃ ಶತ್ರೌ ಚ ಮಿತ್ರೇ ಚ ತಥಾ  ಮಾನ  ಅಪಮಾನಯೋಃ |\nಶೀತ ಉಷ್ಣ ಸುಖ ದುಃಖೇಷು ಸಮಃ ಸಂಗವಿವರ್ಜಿತಃ -- ಹಗೆಯ-ಗೆಳೆಯರಲ್ಲಿ ಭೇದ ಬಗೆಯದವನು; ಗೌರವ-ಅಗೌರವಗಳನ್ನು, ಶೀತ-ಉಷ್ಣಗಳನ್ನು, ಸುಖ-ದುಃಖಗಳನ್ನು ಸಮನಾಗಿ ಕಾಣುವವನು; ಯಾವುದಕ್ಕೂ ಅಂಟಿಕೊಳ್ಳದವನು;\n\nಭಗವಂತನಿಗೆ ಪ್ರಿಯನಾದ ಭಕ್ತನ ಲಕ್ಷಣಗಳ ಸರಣಿ ಮುಂದುವರಿಯುತ್ತದೆ. 'ಸಮಃ ಶತ್ರೌ ಚ ಮಿತ್ರೇ ಚ' — ಶತ್ರು ಮತ್ತು ಮಿತ್ರರಲ್ಲಿ ಭೇದ ಮಾಡದಿರುವುದು. 'ಮಾನಾಪಮಾನಯೋಃ' — ಮಾನ-ಅಪಮಾನಗಳಲ್ಲಿ ಸಮಚಿತ್ತತೆ. 'ಸಂಗವಿವರ್ಜಿತಃ' — ಆಸಕ್ತಿಯನ್ನು ತೊರೆದಿರುವುದು.",
  "12.19": "ತುಲ್ಯ ನಿಂದಾ ಸ್ತುತಿಃ ಮೌನೀ ಸಂತುಷ್ಟಃ ಯೇನ ಕೇನಚಿತ್‌ |\nಅನಿಕೇತಃ ಸ್ಥಿರ ಮತಿಃ ಭಕ್ತಿಮಾನ್‌ ಮೇ ಪ್ರಿಯಃ ನರಃ -- ಹೊಗಳಿಕೆಯನ್ನು ತೆಗಳಕೆಯಂತೆ ಕಾಣುವವನು; ಚಿಂತನಶೀಲನು; ಏನು ಇದೆಯೋ ಅಷ್ಟರಲ್ಲಿ ತೃಪ್ತನಾದವನು; ಒಂದೆಡೆ ನೆಲೆನಿಲ್ಲದವನು [ಭಗವಂತನಲ್ಲಿ ನೆಲೆ ನಿಂತವನು;] ಭಗವಂತನ ಅರಿವು ಗಟ್ಟಿಗೊಂಡವನು-ಭಕ್ತನಾದ ಇಂತಹ ಮನುಜ ನನಗೆ ಅಚ್ಚುಮೆಚ್ಚು.\n\nಸಾಮಾನ್ಯವಾಗಿ ನಾವು. ಶತ್ರು ಅಥವಾ ಮಿತ್ರ ಅನ್ನುವ ಭಾವನೆಯನ್ನು ವ್ಯಾವಹಾರಿಕವಾಗಿ\nರೂಢಿಸಿಕೊಳ್ಳುತ್ತೇವೆ. ನಮ್ಮನ್ನು ಹೊಗಳುವವರು ನಮಗೆ ಮಿತ್ರರು, ನಮ್ಮ ತಪ್ಪನ್ನು ತೆಗಳುವವರು ಶತ್ರುಗಳು.\nಇದು ನಮ್ಮ ಅಪ್ರಭುದ್ಧ ನಡೆ. ಸ್ನೇಹದ ಹಿಂದೆ ದ್ವೇಷವಿರಬಹುದು, ದ್ವೇಷದ ಹಿಂದೆ ಸ್ನೇಹವಿರಬಹುದು.\nಪುರಂದರದಾಸರು “ನಿಂದಕರಿರಬೇಕು' ಎಂದು ಹಾಡಿರುವುದನ್ನು ನಾವು ಇಲ್ಲಿ ನೆನಪಿಸಿಕೊಳ್ಳಬಹುದು.\nನಿಂದಕರು. ನಮ್ಮ ನಿಂದೆ. ಮಾಡುವ ಮೂಲಕ ನಮ್ಮಲ್ಲಿರುವ ನಿಂದ್ಯವಾದ ದೋಷಗಳ ಫಲವನ್ನು\nತೆಗೆದುಕೊಳ್ಳುತ್ತಾರೆ. ಹೊಗಳುವವರು ಹೊಗಳುವ ಮೂಲಕ ನಮ್ಮಲ್ಲಿರುವ ಒಳ್ಳೆಯತನದ ಪುಣ್ಯದ ಫಲದ\n\nಪಾಲನ್ನು ಪಡೆಯುತ್ತಾರೆ. ಆದ್ದರಿಂದ ಸಾಧನೆಯ ಮಾರ್ಗದಲ್ಲಿ ಹೊಗಳುವವರಿಗಿಂತ ನಿಂದಕರು ಸಹಾಯಕರು.\nಈ ಕಾರಣದಿಂದ ಶತ್ರು ಮಿತ್ರ ಎನ್ನುವ ಪರಿಭೇದ ಮಾಡಿಕೊಂಡು ಯಾರನ್ನೋ ಟೀಕೆ ಮಾಡುವುದಾಗಲಿ, ದ್ವೇಷ\nಕಟ್ಟಿಕೊಳ್ಳುವುದಾಗಲಿ ಮಾಡಿಕೊಳ್ಳಬೇಡ. ದುರ್ಗುಣದಿಂದ ದೂರವಿರು. ಒಳ್ಳೆಯ ಗುಣವನ್ನು ಪ್ರೀತಿಸು. ಎಲ್ಲಿ\nಒಳ್ಳೆಯತನವಿದೆಯೋ ಅವರ ಒಡನಾಟಮಾಡುಮೈತ್ರಿ); ದುಃಖವನ್ನು ಕಂಡು ಕರಗು(ಕರುಣ); ಇನ್ನೊಬ್ಬರ\nಸಂತೋಷವನ್ನು ಕಂಡು ಸಂತೋಷಪಡು(ಮುದಿತ); ಕೆಟ್ಟತನದಿಂದ ದೂರವಿರು(ಉಪೇಕ್ಷ). ಮೂಲಭೂತವಾಗಿ\nಶತ್ರು ಮಿತ್ರ ಎನ್ನುವ ವಿಭಾಗ ಬೇಡ. ಎಲ್ಲರಲ್ಲಿಯೂ ಭಗವಂತನನ್ನು ಕಾಣು. ಲೌಕಿಕ ಶತ್ರು-ಮಿತ್ರ ಭಾವನೆಯನ್ನು\nಬಿಟ್ಟುಬಿಡು.\n\nಸನ್ಮಾನ ಮಾಡಿದಾಗ ಉಬ್ಬಬೇಡ. ಅವಮಾನ ಮಾಡಿದಾಗ ಕುಗ್ಗಬೇಡ. ಮಾನ-ಅವಮಾನವನ್ನು ಗೆಲ್ಲು.\nಇನ್ನೊ ಬ್ಬರು ಏನು ಹೇಳಿದರು ಎನ್ನು ವುದು ಮುಖ್ಯವಲ್ಲ. ನಮ್ಮ ಅಂತರಾತ್ಮ ಏನು ಎನ್ನುವುದು ಮುಖ್ಯ.\nಇನ್ನೊಬ್ಬ ರು ಹೊಗಳಿದಾಗ ನಮ್ಮಲ್ಲಿ ಇಲ್ಲದ ಗುಣ ನಮ್ಮನ್ನು ಬಂದು ಸೇರುವುದಿಲ್ಲ. ಅದೇ ರೀತಿ ಇನ್ನೊ ಬ್ಬರು\nತೆಗಳಿದಾಗ ನಾವು ಕೆಳಗೆ ಹೋಗುವುದಿಲ್ಲ. ಹೊಗಳಿಕೆ ಬಗ್ಗೆ ನಾವು ಎಚ್ಚರದಿಂದಿರಬೇಕು. ಏಕೆಂದರೆ ಅದರಿಂದ\nನಾವು ದಾರಿ ತಪ್ಪುವ ಸಾಧ್ಯತೆ ಹೆಚ್ಚು. ಅವಮಾನದಿಂದ ನಾವು ತಪ್ಪು ದಾರಿಯನ್ನು ಬಿಟ್ಟು ಸರಿ ದಾರಿಯಲ್ಲಿ ಸಾಗಿ\nಎತ್ತರಕ್ಕೇರುವ ಸಾಧ್ಯತೆ ಇದೆ.\n\nಸುಖ-ದುಃಖವನ್ನು ಸಮನಾಗಿ ಕಾಣು. ಯಾವುದೇ ವಸ್ತು ನಮಗೆ ಸುಖ-ದುಃಖವನ್ನು ಕೊಡುವುದಿಲ್ಲ. ಆ ವಸ್ತುವನ್ನು\nನಾವು ನೋಡುವ ಭಾವನೆ ನಮಗೆ ಸುಖ-ದುಃಖವನ್ನು ಕೊಡುತ್ತದೆ. ಆದ್ದರಿಂದ ಶೀತ-ಉಷ್ಣದಂತೆ ಸುಖ-\nದುಃಖವನ್ನು ಸಮನಾಗಿ ಕಾಣುವುದನ್ನು ರೂಢಿಸಿಕೋ.\n\nನಮಗನಿಸುತ್ತದೆ ಇವೆಲ್ಲವೂ ಮಾನವ ಸಹಜಪ್ರವೃತ್ತಿ ಎಂದು. ಆದರೆ ಇದು ಸಹಜ ಧರ್ಮವಲ್ಲ. ನಾವು\nಅಂಟಿಸಿಕೊಳ್ಳುವುದರಿಂದ ನಮ್ಮಲ್ಲಿ ನಮಗೆ ಬೇಡವಾದ ಈ ಗುಣಗಳು ತುಂಬಿಕೊಳ್ಳುತ್ತವೆ. ಆದ್ದರಿಂದ\nಹೊಗಳಿಕೆ ಮತ್ತು ತೆಗಳಿಕೆಗೆ ತಕ್ಷಣ ಪ್ರತಿಕ್ರಿಯಿಸಬೇಡ. ಮೌನಿಯಾಗು. ವಿಷಯದ ಬಗ್ಗೆ ಮನನ ಮಾಡು.\nದುಡುಕಬೇಡ. ಎಷ್ಟು ಕಡಿಮೆ ಮಾತನಾಡಲು ಸಾಧ್ಯವೋ ಅಷ್ಟು ಕಡಿಮೆ ಮಾತನಾಡು. ಯೋಚಿಸಿ ಮಾತನಾಡು.\nಏನಿದೆಯೋ ಅದನ್ನು ತೃಪ್ತಿಯಿಂದ ಅನುಭವಿಸು. ಸ್ಥಿರ-ಚರ ವಸ್ತುಗಳ(Movable and immovable) ಹಿಂದೆ\nಹೋಗಬೇಡ. ಭಗವಂತ ಕೊಟ್ಟಿರುವುದರಲ್ಲಿ ಸಂತೋಷದಿಂದ ನಿಶ್ಚಿಂತೆಯಿಂದ ಬದುಕು. ಭಕ್ತಿಯಿಂದ\nಭಗವಂತನಲ್ಲಿ ಶರಣಾದಾಗ ನಾವು ನಮ್ಮ ಸಾಧನೆಯ ಹಾದಿಯಲ್ಲಿ ಈ ಎತ್ತರಕ್ಕೇರಬಹುದು. “ಇಂತಹ\nಗುಣವನ್ನು ಹೊಂದಿರುವ ಭಕ್ತ ನನಗೆ ಅಚ್ಚುಮೆಚ್ಚು' ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.\n",
  "12.20": "ಯೇತುಧರ್ಮ ಅಮೃತಮ್‌ ಇದಮ್‌ ಯಥಾ ಉಕ್ತಮ್‌ ಪರ್ಯುಪಾಸತೇ |\n\nಶ್ರದ್ಧಧಾನಾಃ ಮತ್‌ ಪರಮಾಃ ಭಕ್ತಾಃ ತೇ ಅತೀವ ಮೇ ಪ್ರಿಯಾಃ -ಧರ್ಮ ಮೋಕ್ಷಗಳಿಗೆ ಸಾಧನವಾದ ಈ ಭಕ್ತಿ\nಯೋಗವನ್ನು ಇಲ್ಲಿ ಹೇಳಿದ ರೀತಿ ಆಚರಿಸುವವರು, ನನ್ನ ಹಿರಿಮೆಯನ್ನು ನಂಬಿ ನಡೆದು ನನ್ನಲ್ಲಿ ಭಕ್ತಿಯಿಟ್ಟವರು -\nಅಂತವರು ನನಗೆ ತುಂಬಾ ಅಚ್ಚುಮೆಚ್ಚು.\n\nನಮ್ಮ ಭಕ್ತಿ ಹೇಗಿರಬೇಕು, ಭಕ್ತನಲ್ಲಿರಬೇಕಾದ ಗುಣಗಳೇನು ಎನ್ನುವ ಈ ಅಮೃತ(ಮೋಕ್ಬಸಾಧನಾ\nಧರ್ಮವನ್ನು ವಿವರಿಸಿದ ಕೃಷ್ಣ, ಇಲ್ಲಿ ಫಲಶ್ರುತಿಯಾಗಿ ಹೇಳುತ್ತಾನೆ: “ಇಲ್ಲಿ ಹೇಳಿದಂತೆ ಉಪಾಸನೆ\nಮಾಡುವವರು, ಗುಣಧರ್ಮವನ್ನು ಬೆಳೆಸಿಕೊಂಡವರು, ಭಕ್ತಿಯಿಂದ ಆಚರಣೆಗೆ ತಂದುಕೊಳ್ಳುವ ಭಕ್ತರು ನನಗೆ\nಪರಮ ಪ್ರಿಯರು” ಎಂದು.\nಇತಿ ದ್ವಾದಶೋ*ಧ್ಯಾಯಃ\nಹನ್ನೆರಡನೆಯ ಅಧ್ಯಾಯ ಮುಗಿಯಿತು\n\nಅಧ್ಯಾಯ ಹದಿಮೂರು\n\nಇದು ಭಗವದ್ಗೀತೆಯ ಮೂರನೇ ಷಟ್ಕದ ಮೊದಲ ಅಧ್ಯಾಯ. ಗೀತೆಯ ಈ ಹದಿಮೂರನೇ ಅಧ್ಯಾಯ ಒಂದು\nಅಪೂರ್ವ ಅಧ್ಯಾಯ. ಈ ಹಿಂದಿನ ಹನ್ನೆರಡು ಅಧ್ಯಾಯಗಳಲ್ಲಿ ಏನು ಹೇಳಲಾಗಿದೆಯೋ ಅವೆಲ್ಲವನ್ನೂ ಸಂಗ್ರಹ\nಮಾಡಿ ಈ ಅಧ್ಯಾಯದಲ್ಲಿ ಹೇಳಲಾಗಿದೆ. ಆದ್ದರಿಂದ ಹಿಂದಿನ ಎರಡು ಷಟ್ಕಗಳಲ್ಲಿ ಕಂಡ ವಿಷಯಗಳ ಪೂರ್ಣ\nವಿಶ್ಲೇಷಣೆ ಈ ಅಧ್ಯಾಯ. ಜಡಪ್ರಪಂಚ, ಅದರಲ್ಲಿ ಪ್ರಕೃತಿಯಲ್ಲಿ ಬದ್ಧನಾಗಿ, ಪ್ರಕೃತಿಯಿಂದ ಪಾರಾಗಲು\nಬಯಸುವ ಜೀವ. ಪಾರಾಗುವುದಕ್ಕೋಸ್ಕರ ಜ್ಞಾನದ ಅನುಸಂಧಾನ ಮತ್ತು ಸಾಧನೆ- ಈ ಎಲ್ಲಾ ವಿಷಯಗಳನ್ನು\nನಾವು ಹಿಂದಿನ ಅಧ್ಯಾಯಗಳಲ್ಲಿ ವಿಕ್ಷಿಪ್ತವಾಗಿ ನೋಡಿದ್ದೇವೆ. ಅದೆಲ್ಲವುದರ ಒಂದು ಸಮಷ್ಠಿ ಸಂಗ್ರಹ(ಸರ್ವಾರ್ತ\nಸಂಕ್ಷೇಪಃ) ಈ ಅಧ್ಯಾಯ. ಈ ಅಧ್ಯಾಯ ಗೀತೆಯಲ್ಲಿ ಅತ್ಯಂತ ಗ್ರಾಹ್ಯವಾದ ಅಧ್ಯಾಯ.\n\nಇಲ್ಲಿ ಪ್ರಾರಂಭದಲ್ಲಿ ಒಂದು ಶ್ಲೋಕವಿದೆ. ಈ ಅಧ್ಯಾಯದಲ್ಲಿ ಮುಂದೆ ಏನು ವಿವರಣೆ ಬರುತ್ತದೆ, ಅದನ್ನು ತಾನು\nತಿಳಿಯಬೇಕೆಂದು ಅರ್ಜುನ ಕೃಷ್ಣನನ್ನು ಕೇಳುವ ಶ್ಲೋಕ. ಈ ಶ್ಲೋಕ ಹೀಗಿದೆ:\n\nಪ್ರಕೃತಿಂ ಪುರುಷಂ ಚೈವ ಕ್ಷೇತ್ರಂ ಕ್ಷೇತ್ರಜ್ಞಮೇವ ಚ |\nಏತದ್‌ ವೇದಿತುಮಿಚ್ಛಾಮಿ ಜ್ಞಾನಂ ಜ್ಞೇಯಂ ಚ ಕೇಶವ ॥*॥\n\nಅರ್ಥಾತ್‌- “ಕೇಶವಾ, ನಾನಿದನ್ನು ತಿಳಿಯಬಯಸುತ್ತೇನೆ: ಪ್ರಕೃತಿಯನ್ನು, ಪುರುಷನನ್ನು, ಕ್ಷೇತ್ರವನ್ನು,\nಕ್ಷೇತ್ರಜ್ಞನನ್ನು, ಜ್ಞಾನವನ್ನು ಮತ್ತು ಜ್ಞೇಯವನ್ನು”.\n\nವಾಸ್ತವವಾಗಿ ಈ ಶ್ಲೋಕ ಭಗವದ್ಗೀತೆಯ ಶ್ಲೋಕವಲ್ಲ. ಪ್ರಾಚೀನ ಭಾಷ್ಯಕಾರರು ಯಾರೂ ಈ ಶ್ಲೋಕವನ್ನು\nಗೀತೆಯ ಶ್ಲೋಕವೆಂದು ಪರಿಗಣಿಸಿಲ್ಲ. ಬಹಳ ಮಂದಿಯ ಅಭಿಪ್ರಾಯದಂತೆ ಇದು ಪ್ರಕ್ಷಿಪ್ತ್ಪಶ್ಲೋಕ*. ಗೀತೆಯಲ್ಲಿ\nಒಟ್ಟು ಏಳುನೂರು ಶ್ಲೋಕಗಳಿವೆ. ಅದಕ್ಕಾಗಿ ಗೀತೆಯನ್ನು 'ಸಪ್ತಶತಿ' ಎಂದು ಕರೆಯುತ್ತಾರೆ. [ಇದಕ್ಕಾಗಿ\nವಾದಿರಾಜರು ತಮ್ಮ ಯುಕ್ತಿಮಲ್ಲಿಕಾದಲ್ಲಿ ಬ್ರಹ್ಮಸೂತ್ರ ಮತ್ತು ಭಗವದ್ಗೀತೆಯನ್ನು ರಚಿಸಿದ ವೇದವ್ಯಾಸರನ್ನು\n\"ಸೂತ್ರಸಪ್ತಶತೀಪತೇ' ಎಂದು ಸಂಬೊಧಿಸಿದ್ದಾರೆ. ಇಂತಹ ಏಳುನೂರು ಶ್ಲೋಕಗಳಿರುವ ಭಗವದ್ಗೀತೆಗೆ ಈ\nಮೇಲಿನ ಶ್ಲೋಕವನ್ನು ಸೇರಿಸಿದರೆ ಒಟ್ಟು ಏಳುನೂರ ಒಂದು ಶ್ಲೋಕವಾಗುತ್ತದೆ. ಇನ್ನು ಈ ಶ್ಲೋಕದಲ್ಲಿ\nಕೇಳಲಾದ ಪ್ರಶ್ನೆ ಗೆ ಸಂಬಂಧಪಟ್ಟ ತೆ ಹಿಂದಿನ ಅಧ್ಯಾಯದ ಕೊನೆಯಲ್ಲಿ ಎಲ್ಲೂ ಕೃಷ್ಣ ಉಲ್ಲೇಖ ಮಾಡಿಲ್ಲ. ಈ\nಕಾರಣದಿಂದ ಇಲ್ಲಿ ಅರ್ಜುನ ಈ ರೀತಿ ಪ್ರಶ್ನೆ ಮಾಡುವ ಸಾಧ್ಯತೆ ಇಲ್ಲ. ಆದ್ದರಿಂದ ಈ ಶ್ಲೋಕ ಪ್ರಕ್ಷಿಪ್ತಶ್ಲೋಕ.\nಗೀತೆಯ ಏಳುನೂರು ಶ್ಲೋಕಗಳಲ್ಲಿ ಇದು ಸೇರಿಲ್ಲ.\n\nನೇರವಾಗಿ ಕೃಷ್ಣ ಅರ್ಜುನನಿಗೆ ಕ್ಷೇತ್ರ ಮತ್ತು ಕ್ಷೇತ್ರಜ್ಞ ಎನ್ನುವುದರ ಶಾಸ್ತ್ರೀಯ ಅರ್ಥವನ್ನು\nವಿವರಿಸುವುದರೊಂದಿಗೆ ಈ ಅಧ್ಯಾಯ ಆರಂಭವಾಗುತ್ತದೆ.\n\nಭಗವಾನುವಾಚ ।\nಇದಂ ಶರೀರಂ ಕೌಂತೇಯ ಕ್ಷೇತ್ರಮಿತ್ಯಭಿಧೀಯತೇ |\nಏತದ್‌ ಯೋ ವೇತ್ತಿ ತಂ ಪ್ರಾಹುಃ ಕ್ಷೇತ್ರಜ್ಞ ಇತಿ ತದ್ವಿದಃ ॥೧॥\n\nಭಗವಾನ್‌ ಉವಾಚ-ಭಗವಂತ ಹೇಳಿದನು:\n\nಇದಮ್‌ ಶರೀರಮ್‌ ಕೌಂತೇಯ ಕ್ಷೇತ್ರಮ್‌ ಇತಿ ಅಭಿಧೀಯತೇ ।\n\nಏತತ್‌ ಯಃ ವೇತ್ತಿ ತಮ್‌ ಪ್ರಾಹುಃ ಕ್ಷೇತ್ರಜ್ಞಃ ಇತಿ ತತ್‌ ವಿದಃ -ಭಗವಂತನ ಶರೀರದಂತಿರುವ ಈ ಚರಾಚರ\nವಿಶ್ವ *ಕ್ಷೇತ್ರ' ಎನಿಸಿದೆ. ಇದನ್ನು ಅರಿತವನನ್ನು ಬಲ್ಲವರು *ಕ್ಷೇತ್ರಜ್ಞ' ಎನ್ನುತ್ತಾರೆ.\n\nಕ್ಷೇತ್ರ' ಅನ್ನುವ ಪದಕ್ಕೆ ಒಂದು ನಿಶ್ಚಿತ ಅರ್ಥವಿಲ್ಲ. ಈ ಶ್ಲೋಕದಲ್ಲಿ ಕ್ಷೇತ್ರಂ ಅನ್ನುವ ಪದವನ್ನು ಯಾವ ರೀತಿ\nಅರ್ಥಮಾಡಿಕೊಳ್ಳಬೇಕು ಎನ್ನುವ ಸುಳಿವನ್ನು ಕೃಷ್ಣ ಕೊಟ್ಟಿದ್ದಾನೆ. ಕ್ಷೇತ್ರ ಎಂದರೆ “ಇದಂ ಶರೀರಂ' ಎಂದಿದ್ದಾನೆ\nಕೃಷ್ಣ. ಆದ್ದರಿಂದ ಇಲ್ಲಿ ಕ್ಷೇತ್ರ ಎಂದರೆ ಜೀವ ವಾಸಮಾಡುವ ನೆಲೆಮನೆ, ಪಿಂಡಾಂಡದಿಂದ- ಬ್ರಹ್ಮಾಂಡದ ತನಕ\nಎಲ್ಲವೂ ಹೌದು. ಈ ಬ್ರಹ್ಮಾಂಡಕ್ಕೆ 'ಕ್ಷೇತ್ರ ಮತ್ತು ಶರೀರ' ಅನ್ನು ವುದು ಅನ್ವರ್ಥನಾಮ(6॥860. ಇಂತಹ\nಕ್ಷೇತ್ರವನ್ನು ಯಾರು ಸಮಗ್ರವಾಗಿ ತಿಳಿದಿದ್ದಾನೋ ಅವನು ಕ್ಷೇತ್ರಜ್ಞ. ಯಾರೀತ? ಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ\nನೋಡೋಣ.\n\nಕ್ಷೇತ್ರಜ್ಞಂ ಚಾಪಿ ಮಾಂ ವಿದ್ಧಿ ಸರ್ವಕ್ಷೇತ್ರೇಷು ಭಾರತ |\n\nಕ್ಷೇತ್ರಕ್ಷೇತ್ರಜ್ಞಯೋರ್ಜಾನಂ ಯತ್‌ ತಜ್‌ ಜ್ಞಾನಂ ಮತಂ ಮಮ ॥೨॥\n\nಕ್ಷೇತ್ರಜ್ಞಮ್‌ ಚ ಅಪಿ ಮಾಮ್‌ ವಿದ್ಧಿ ಸರ್ವ ಕ್ಷೇತ್ರೇಷು ಭಾರತ ।\n\nಕ್ಷೇತ್ರ ಕ್ಷೇತ್ರಜ್ಞಯೋಃ ಜ್ಞಾನಮ್‌ ಯತ್‌ ತತ್‌ ಜ್ಞಾನಮ್‌ ಮತಮ್‌ ಮಮ -ಓ ಭಾರತಾ, ಎಲ್ಲಾ ಕ್ಷೇತ್ರಗಳಲ್ಲಿ\nನೆಲೆಸಿರುವ ನನ್ನನ್ನೇ *ಕ್ಷೇತ್ರಜ್ಞ'ನೆಂದು ತಿಳಿ. ಕ್ಷೇತ್ರ ಮತ್ತು ಕ್ಷೇತ್ರಜ್ಞರ ಅರಿವೇ ನಿಜವಾದ 'ಜ್ಞಾನ' ಎನ್ನುವುದು\nನನ್ನ ಅಭಿಪ್ರಾಯ.\n\nಒಳಗೂ ಹೊರಗೂ ತುಂಬಿರುವ, ಎಲ್ಲಾ ಕ್ಷೇತ್ರದಲ್ಲಿರುವ ಭಗವಂತನೇ ಕ್ಷೇತ್ರಜ್ಞ. ಜೀವ ಕೇವಲ ಕ್ಷೇತ್ರಸ್ಥ.\nನಿಜವಾದ ಜ್ಞಾನವೆಂದರೆ ವಿಶ್ವದ ಅರಿವು; ವಿಶ್ವದಲ್ಲಿ ತುಂಬಿರುವ ಭಗವಂತನ ಅರಿವು.",
  "13.1": "ಭಗವಾನ್‌ ಉವಾಚ-ಭಗವಂತ ಹೇಳಿದನು:\n\nಇದಮ್‌ ಶರೀರಮ್‌ ಕೌಂತೇಯ ಕ್ಷೇತ್ರಮ್‌ ಇತಿ ಅಭಿಧೀಯತೇ ।\n\nಏತತ್‌ ಯಃ ವೇತ್ತಿ ತಮ್‌ ಪ್ರಾಹುಃ ಕ್ಷೇತ್ರಜ್ಞಃ ಇತಿ ತತ್‌ ವಿದಃ -ಭಗವಂತನ ಶರೀರದಂತಿರುವ ಈ ಚರಾಚರ\nವಿಶ್ವ “ಕ್ಷೇತ್ರ” ಎನಿಸಿದೆ. ಇದನ್ನು ಅರಿತವನನ್ನು ಬಲ್ಲವರು “ಕ್ಷೇತ್ರಜ್ಞ” ಎನ್ನುತ್ತಾರೆ.\n\nಕ್ಷೇತ್ರ' ಅನ್ನುವ ಪದಕ್ಕೆ ಒಂದು ನಿಶ್ಚಿತ ಅರ್ಥವಿಲ್ಲ. ಈ ಶ್ಲೋಕದಲ್ಲಿ ಕ್ಷೇತ್ರಂ ಅನ್ನುವ ಪದವನ್ನು ಯಾವ ರೀತಿ\nಅರ್ಥಮಾಡಿಕೊಳ್ಳಬೇಕು ಎನ್ನುವ ಸುಳಿವನ್ನು ಕೃಷ್ಣ ಕೊಟ್ಟಿದ್ದಾನೆ. ಕ್ಷೇತ್ರ ಎಂದರೆ “ಇದಂ ಶರೀರಂ' ಎಂದಿದ್ದಾನೆ\nಕೃಷ್ಣ. ಆದ್ದರಿಂದ ಇಲ್ಲಿ ಕ್ಷೇತ್ರ ಎಂದರೆ ಜೀವ ವಾಸಮಾಡುವ ನೆಲೆಮನೆ, ಪಿಂಡಾಂಡದಿಂದ- ಬ್ರಹ್ಮಾಂಡದ ತನಕ\nಎಲ್ಲವೂ ಹೌದು. ಈ ಬ್ರಹ್ಮಾಂಡಕ್ಕೆ 'ಕ್ಷೇತ್ರ ಮತ್ತು ಶರೀರ' ಅನ್ನು ವುದು ಅನ್ವರ್ಥನಾಮ(6॥860. ಇಂತಹ\nಕ್ಷೇತ್ರವನ್ನು ಯಾರು ಸಮಗ್ರವಾಗಿ ತಿಳಿದಿದ್ದಾನೋ ಅವನು ಕ್ಷೇತ್ರಜ್ಞ. ಯಾರೀತ? ಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ\nನೋಡೋಣ.\n\nಕ್ಷೇತ್ರಜ್ಞಂ ಚಾ",
  "13.2": "ಕ್ಷೇತ್ರಜ್ಞಮ್‌ ಚ ಅಪಿ ಮಾಮ್‌ ವಿದ್ಧಿ ಸರ್ವ ಕ್ಷೇತ್ರೇಷು ಭಾರತ ।\n\nಕ್ಷೇತ್ರ ಕ್ಷೇತ್ರಜ್ಞಯೋಃ ಜ್ಞಾನಮ್‌ ಯತ್‌ ತತ್‌ ಜ್ಞಾನಮ್‌ ಮತಮ್‌ ಮಮ -ಓ ಭಾರತಾ, ಎಲ್ಲಾ ಕ್ಷೇತ್ರಗಳಲ್ಲಿ\nನೆಲೆಸಿರುವ ನನ್ನನ್ನೇ “ಕ್ಷೇತ್ರಜ್ಞ”ನೆಂದು ತಿಳಿ. ಕ್ಷೇತ್ರ ಮತ್ತು ಕ್ಷೇತ್ರಜ್ಞರ ಅರಿವೇ ನಿಜವಾದ 'ಜ್ಞಾನ' ಎನ್ನುವುದು\nನನ್ನ ಅಭಿಪ್ರಾಯ.\n\nಒಳಗೂ ಹೊರಗೂ ತುಂಬಿರುವ, ಎಲ್ಲಾ ಕ್ಷೇತ್ರದಲ್ಲಿರುವ ಭಗವಂತನೇ ಕ್ಷೇತ್ರಜ್ಞ. ಜೀವ ಕೇವಲ ಕ್ಷೇತ್ರಸ್ಥ.\nನಿಜವಾದ ಜ್ಞಾನವೆಂದರೆ ವಿಶ್ವದ ಅರಿವು; ವಿಶ್ವದಲ್ಲಿ ತುಂಬಿರುವ ಭಗವಂತನ ಅರಿವು. ಈ ವಿಶ್ವದೊಳಗೆ ನಾವು\nಹೇಗಿದ್ದೇವೆ? ಈ ವಿಶ್ವ ನಮಗೆ ಹೇಗೆ ಬಂಧಕವಾಗಿದೆ? ಈ ಬಂಧನವನ್ನು ಕಳಚಿಕೊಂಡು ಆ ವಿಶ್ವಾತ್ಮ\nಭಗವಂತನನ್ನು ನಾವು ಸೇರುವುದು ಹೇಗೆ? ಈ ಅರಿವೇ ಜ್ಞಾನ. ಹಿಂದಿನ ಅಧ್ಯಾಯದಲ್ಲಿ ಹೇಳಿದಂತೆ ನಾವು\nಹದಿನೈದು. ಬೇಲಿಗಳ ಸೆರೆಮನೆಯಲ್ಲಿದ್ದೇವೆ. ಆದರೆ ಇದು ಶಿಕ್ಷೆಯಲ್ಲ, ಶಿಕ್ಷಣ. ಈ ಬಂಧನದಿಂದ\nಪಾರಾಗಬೇಕಾದರೆ ಭವಮೋಚಕನಾದ ಕ್ಷೇತ್ರಜ್ಞನನ್ನು ತಿಳಿಯಬೇಕು. ಈ ಎಚ್ಚರವೇ ನಿಜವಾದ ಜ್ಞಾನ.\n",
  "13.3": "ತತ್‌ ಕ್ಷೇತ್ರಮ್‌ ಯತ್‌ ಚ ಯಾದೃಕ್‌ ಚ ಯತ್‌ ವಿಕಾರಿ ಯತಃ ಚಯತ್‌ |\n\nಸಃ ಚ ಯಃ ಯತ್‌ ಪ್ರಭಾವಃ ಚ ತತ್‌ ಸಮಾಸೇನ ಮೇ ಶೃಣು - ಆ ಕ್ಷೇತ್ರವೆಂದರೇನು? ಅದು ಎಂತಹದು?\nಅದರ ವಿಕಾರಗಳೇನು? ಅದರ ಪ್ರೇರಕ ಶಕ್ತಿ ಯಾರು? ಅವನು ಎಂತವನು ? ಅವನ ಹಿರಿಮೆಗಳೇನು? ಅದನ್ನು\nಅಡಕವಾಗಿ ನನ್ನಿಂದ ಕೇಳು.\n\nಮೊದಲು ಕ್ಷೇತ್ರವೆಂದರೇನು? ಬ್ರಹ್ಮಾಂಡ ಮತ್ತು ಪಿಂಡಾಂಡ ಹೇಗೆ ಮತ್ತು ಯಾವುದರಿಂದ ನಿರ್ಮಾಣವಾಗಿದೆ?\nಅದರ ಗುಣಧರ್ಮವೇನು? ಅದು ಯಾವ ಯಾವ ರೀತಿ ರೂಪಾಂತರಗೊಳ್ಳುತ್ತದೆ? ಈ ಬದಲಾವಣೆಗಳು\nಹೇಗಾಗುತ್ತದೆ? ಯಾರಿಂದ ಆಗುತ್ತದೆ? ಇದೆಲ್ಲವನ್ನು ಸೂತ್ರರೂಪವಾಗಿ ಸಂಕ್ಷಿಪ್ತವಾಗಿ, ಚುಟುಕಾಗಿ ನನ್ನಿಂದ\nಕೇಳು.\n",
  "13.4": "ಖಪಿಭಿಃ ಬಹುಧಾ ಗೀತಮ್‌ ಛಂದೋಭಿಃ ವಿವಿಧೈಃ ಪೃಥಕ್‌ ।\nಬ್ರಹ್ಮಸೂತ್ರಪದೈಃ ಚ ಏವ ಹೇತುಮದ್ಳಿಃ ವಿನಿಶ್ಚಿತೈಃ -ಬಗೆಬಗೆಯ ಬೇರೆಬೇರೆ ಮಂತ್ರಗಳಿಂದ ಖುಷಿಗಳು\nಅದನ್ನು ಬಗೆಬಗೆಯಿಂದ ಹಾಡಿದ್ದಾರೆ. ಯುಕ್ತಿಯಿಂದ ನಿರ್ಣಯಿಸುವ ವೇದಾಂತ ಸೂತ್ರದ ನುಡಿಗಳೂ ಕೂಡಾ.",
  "13.5": "ಜ್ಞಾನಿಗಳು ಕೂಡಾ ಈ ವಿಚಾರವನ್ನು ಒಬ್ಬೊಬ್ಬರು ಒಂದೊಂದು ರೀತಿ ಹೇಳುತ್ತಾರೆ. ಅದು ಅವರ ಅನುಭವಕ್ಕೆ\nಸೀಮಿತವಾಗಿರುತ್ತದೆ. ಬ್ರಹ್ಮಸೂತ್ರದಲ್ಲಿ ಹೇಳಿರುವ ವಿಚಾರ ಸುಲಭವಾಗಿ ಅರ್ಥವಾಗದು. ಆದ್ದರಿಂದ ನಿಜವನ್ನು\nಕ್ಷೇತ್ರಜ್ಞನಾದ ನಾನೇ ನೇರವಾಗಿ ಹೇಳುತ್ತೇನೆ ಕೇಳು.",
  "13.6": "ಮಹಾಭೂತಾನಿ[ಮಹಾನ್‌ ಭೂತಾನಿ]ಅಹಂಕಾರ:ಃ ಬುದ್ಧಿಃ ಅವ್ಯಕ್ತಮ್‌ ಏವ ಚ।\nಇಂದ್ರಿಯಾಣಿ ದಷ ಏಕಮ್‌ ಚ ಪಂಚ ಚ ಇಂದ್ರಿಯ ಗೋಚರಾಃ ॥\n\nಇಚ್ಛಾ ದ್ವೇಷಃ ಸುಖಂ ದುಃಖಂ ಸಂಘಾತಃ ಚೇತನಾ ಧೃತಿಃ |\n\nಏತತ್‌ ಕ್ಷೇತ್ರಂ ಸಮಾಸೇನ ಸವಿಕಾರಮ್‌ ಉದಾಹೃತಮ್‌ -- ಮಣ್ಣು[ಪೃಥಿವಿ], ನೀರು[ವರುಣ], ಬೆಂಕಿ[ಅಗ್ನಿ 1:\nಗಾಳ್ವ[ವಾಯುಪುತ್ರ ಮರೀಚಿ], ಬಾನು[ಅವಕಾಶ ದೇವತೆ, ವಿಘ್ನ ನಾಶ-ವಿನಾಯಕ-ಗಣಪತಿ]-ಎಂಬ ಐದು\nಮಹಾಭೂತಗಳು. ಅಹಂಕಾರತತ್ವ [್ರಹ್ಮವಾಯು ಮತ್ತು ಶಿವ], ಬುದ್ಧಿತತ್ವ[ಪಾರ್ವತಿ], ಮೂಲಪ್ರಕೃತಿ[ಶ್ರಿ,,\nಕಿವ[ಚಂದ್ರ।೦,, ತೊಗಲು[ವಾಯುಪುತ್ರ ಮರುತ್‌], ಕಣ್ಣು[ಸೂರ್ಯ], ನಾಲಿಗೆ(ವರುಣ], ಮೂಗು[ಅಶ್ವಿಗಳು],\nಬಾಯಿ [ಅಗ್ನಿ], ಕೈಗಳು[ವಾಯುಪುತ್ರರಿಬ್ಬ ರು], ಕಾಲುಗಳು[ಇಂದ್ರ ಪುತ್ರರಾದ ಯಜ್ಞ(ಜಯತ) ಮತ್ತು ಶಂಭು],\nಪಾಯು[ಯಮ], ಉಪಸ್ಥ[ಲಿಂಗ ದೇವತೆ ಶಿವ-ಗಂಡಸರಲ್ಲಿ ; ಸ್ವಾಯಂಭುವಮನು-ಸ್ತ್ರೀಯರಲ್ಲಿ] ಹೀಗೆ ಹತ್ತು\nಇಂದ್ರಿಯಗಳು. ಹನ್ನೊಂದನೆಯದು ಮನಸ್ತತ್ವ[ಇಂದ್ರ, ಕಾಮ ಮತ್ತು ಅನಿರುದ್ಧ] ಮತ್ತು ಐದು ಜ್ಞಾನೇಂದ್ರಿಯ\nವಿಷಯಗಳು: ಶಬ್ಧ, ಸ್ಪರ್ಶ, ರೂಪ, ರಸ ಮತ್ತು ಗಂಧ[ರುದ್ರ ಪುತ್ರರಾದ ಪ್ರಾಣ, ಅಪಾನ, ವ್ಯಾನ, ಉದಾನ\nಮತ್ತು ಸಮಾನ]ಇವು ೨೪ ಅಡಕವಾಗಿ ಕ್ಷೇತ್ರಗಳು.\n\nಬಯಕೆ[ಶ್ರೀ ಮತ್ತು ಭಾರತಿ], ದ್ವೇಷ[(ದ್ವಾಪರ-ಶಕುನಿ], ಸುಖ[ಮುಖ್ಯಪ್ರಾಣ-ವಾಯು-ಭೀಮ], ದುಃಖ[ಕಲಿ-\nದುರ್ಯೋಧನ], ಸಮಷ್ಟಿಶರೀರ[ಶರೀರದಲ್ಲಿರುವ ಅಭಿಮಾನಿ ಜೀವ; ಸಮಸ್ತ ಅಭಿಮಾನಿ ದೇವತೆಗಳು],\nನೆನಪಿನ ಹರಹು[ಶ್ರೀ], ಧೈರ್ಯ[ಸರಸ್ವತಿ ಮತ್ತು ಭಾರತಿ] ಇವು ಏಳು ವಿಶೇಷ ಕ್ರಿಯೆಗಳಾದ ವಿಕಾರಗಳು. ಹೀಗೆ\nವಿಕಾರಗಳ ಜೊತೆಗೆ ಕ್ಷೇತ್ರವನ್ನು ಅಡಕವಾಗಿ ಹೇಳಿದ್ದಾಯಿತು.\n\nಈ ಎರಡು ಶ್ಲೋಕಗಳಲ್ಲಿ ಕೃಷ್ಣ ಕ್ಷೇತ್ರ ಮತ್ತು ಕ್ಷೇತ್ರದ ವಿಕಾರವನ್ನು ವಿವರಿಸಿದ್ದಾನೆ. ಕ್ಷೇತ್ರ ಎನ್ನುವ ಅಖಂಡ\nಘಟಕದೊಳಗೆ ಇರುವ ಜಗತ್ತಿನ ಘಟಕಾಂಶಗಳನ್ನು ಕೃಷ್ಣ ಇಲ್ಲಿ ಸೂತ್ರ ರೂಪದಲ್ಲಿ ಅಡಕವಾಗಿ ವಿವರಿಸಿದ್ದಾನೆ.\nಮೊದಲನೆಯದಾಗಿ. ಪಂಚಮಹಾಭೂತಗಳು. ಈ ಐದರಿಂದ ಈ ಪಿಂಡಾಂಡ ಮತ್ತು ಬ್ರಹ್ಮಾಂಡ\nನಿರ್ಮಾಣವಾಗಿದೆ. ಈ ಕಾರಣಕ್ಕಾಗಿ ಬ್ರಹ್ಮಾಂಡವನ್ನು 'ಪ್ರ-ಪಂಚ' ಎಂದು ಕರೆಯುತ್ತಾರೆ. ಈ ಪಂಚ\nಮಹಾಭೂತಗಳೇ ಪ್ರಪಂಚದ ಮೂಲದ್ರವ್ಯ. ಪಿಂಡಾಂಡದಲ್ಲಿ ಈ ಪಂಚ ಮಹಾಭೂತಗಳನ್ನು ಅನ್ನಮಯ ಮತ್ತು\nಪ್ರಾಣಮಯ ಎಂದು ಕರೆಯತ್ತಾರೆ. ಕಾಣುವ ಸ್ಥೂಲ ಶರೀರ ಪ್ರಥಿವಿ ಮತ್ತು ನೀರಿನ ಭಾಗದಿಂದಾಗಿದೆ. ಇಂತಹ\nಸ್ಥೂಲ ಶರೀರದೊಳಗೆ ಕಾಣದ ಪ್ರಾಣಮಯಕೋಶವಿದೆ. ದೇಹದ ಶಾಖ(ಬೆಂಕಿ), ಉಸಿರಾಟ(ಗಾಳಿ) ಮತ್ತು\nಒಳಗೆ ರಕ್ತ-ಗಾಳಿ ಸಂಚಾರದ ಅವಕಾಶ(ಆಕಾಶ). ಇದರಿಂದಾಚೆಗೆ ಮನಸ್ಸು ಮತ್ತು ಬುದ್ಧಿಯನ್ನೂಳಗೊಂಡ\nಮನೋಮಯಕೋಶ, ಅದರಿಂದಾಚೆಗೆ ವಿಜ್ಞಾನಮಯಕೋಶ-ಸ್ಮರಣಶಕ್ತಿ. ಆದ್ದರಿಂದ ಬುದ್ದಿಗೆ ಮೊದಲು\nಅಹಂಕಾರ ಮತ್ತು ಚಿತ್ತ. ಇಲ್ಲಿ ಅಹಂಕಾರ ಅಂದರೆ “ನನ್ನ ಅಸ್ತಿತ್ವದ ಅರಿವು(awareness of self). ಈ\nಅಹಂಕಾರ ತತ್ವ ಪಿಂಡಾಂಡದಲ್ಲಿ ಚಿತ್ತ, ಬ್ರಹ್ಮಾಂಡದಲ್ಲಿ ಮಹತತ್ವ.\n\nವ್ಯಕ್ತವಾಗುವ ಈ ಪ್ರಪಂಚದ ಮೂಲ ಅವ್ಯಕ್ತ. ಸೃಷ್ಟಿಯ ಮೂಲಸ್ಥಿತಿ-ಪ್ರಳಯಸಾಗರ. ಅಂದರೆ\nಪರಮಾಣುರೂಪದಲ್ಲಿ ಚದುರಿಕೊಂಡಿರುವ ಅವ್ಯಕ್ತ ಪ್ರಪಂಚ. ಇಂತಹ ಪ್ರಪಂಚದಲ್ಲಿ ಚತುರ್ಮುಖ\nಮಹತತ್ವವನ್ನು ಸೃಷ್ಟಿ ಮಾಡಿದ. ಪ್ರಳಯ ಸಾಗರದಲ್ಲಿ ತನ್ನ ಅಸ್ತಿತ್ವದ ಅರಿವಿಲ್ಲದೇ ಇದ್ದ ಜೀವಗಳಿಗೆ “ನಾನು'\nಎನ್ನುವ ಅರಿವು ಬರುವುದೇ ಮಹತತ್ವದ ಸೃಷ್ಟಿ. ಚಿತ್ತದ ವ್ಯಾಪ್ತಿ ಚೇತನ. ಇದು ನಮ್ಮ ನೆನಪಿನ ವಿಸ್ತಾರ.\n\nಈ ಶರೀರದಲ್ಲಿ ಐದು ಜ್ಞಾನೇಂದ್ರಿಯಗಳು, ಐದು. ಕರ್ಮೇಂದ್ರಿಯಗಳಿವೆ. ಮತ್ತು ಹನ್ನೊಂದನೇ\nಇಂದ್ರಿಯವಾಗಿರುವುದು ಮನಸ್ಸು. ಕಿವಿಯಿಂದ ಶಬ್ದಗ್ರಹಣ, ಕಣ್ಣಿನಿಂದ ರೂಪ ಗ್ರಹಣ, ಮೂಗಿನಿಂದ ಗಂಧ\nಗ್ರಹಣ, ನಾಲಿಗೆಯಿಂದ ರಸ ಗ್ರಹಣ, ತೊಗಲಿನಿಂದ ಗಾಳಿಯ ಗ್ರಹಣ. ಅದೇ ರೀತಿ ಬಾಯಿ ಮಾತನಾಡಲು, ಕೈ\nಕೆಲಸ ಮಾಡಲು, ಕಾಲು ನಡೆಯಲು. ಈ ಎಂಟನ್ನು ಗ್ರಹ(sense organs)ಗಳೆನ್ನುತ್ತಾರೆ. ನಂತರ ಪಾಯು ಮತ್ತು\nಉಪಸ್ಥ(ವಿಸರ್ಜನಾಂಗ ಮತ್ತು ಸಂತಾನವೃದ್ಧಿ)ಗಳು. ಈ ಎಲ್ಲವನ್ನು ಚಿಂತನೆಗೊಳಪಡಿಸುವ ಹನ್ನೊಂದನೇ\nಇಂದ್ರಿಯ ಮನಸ್ಸು. ಇವೆಲ್ಲವೂ ಕ್ಷೇತ್ರದ ಘಟಕಾಂಶಗಳು. ಸಮಷ್ಟಿಯಾಗಿ ಇದು ಕ್ಷೇತ್ರ. [ಇಲ್ಲಿ ಹೇಳಿರುವ\nಪ್ರತಿಯೊಂದು ಘಟಕದೊಂದಿಗೆ ಅದರ ಅಭಿಮಾನಿ ದೇವತೆಯರೂ ಸೇರಿದ್ದಾರೆ. ಅದನ್ನು ಮೇಲೆ ಸಂಕ್ಷಿಪ್ತವಾಗಿ\nಹೇಳಲಾಗಿದೆ]\n\nಈ ಜಗತ್ತು ಸದಾ ಬದಲಾಗುತ್ತಿರುತ್ತದೆ. ಅದಕ್ಕಾಗಿ ಜಗತ್ತನ್ನು ಅಶ್ವತ್ಥ ಎಂತಲೂ ಕರೆಯುತ್ತಾರೆ. ಅಶ್ವ ನಿರಂತರ\nಚಲನೆಯಲ್ಲಿರುವ ಪ್ರಾಣಿ. ಅದು ನಿಶ್ಚಲವಾಗಿ ಇರುವುದೇ ಇಲ್ಲ. ಈ ಪ್ರಪಂಚ ಕೂಡಾ ಹಾಗೆ ಸದಾ\nಚಲನೆಯಲ್ಲಿರುವುದರಿಂದ-ಅದನ್ನು ಪ್ರಾಚೀನರು ಅಶ್ವತ್ಥ ಎಂದು ಕರೆದರು. ನಮ್ಮ ದೇಹ ಅನ್ನುವುದು ಭೌತಿಕ\nವಿಕಾರ. ಅದರಲ್ಲಿ ಆಗತಕ್ಕಂತಹ ಮಾನಸಿಕ ಪ್ರಪಂಚದ ಎಲ್ಲಾ ತೊಳಲಾಟ ಮಾನಸಿಕ ವಿಕಾರ. ವಿಶೇಷವಾಗಿ\nನಮ್ಮ ಇಚ್ಛೆ(ಬಯಕೆ), (ಅ)ದ್ವೇಷ, ಸುಖ-ದುಃಖ, ನಮ್ಮ ನೆನಪಿನ ಹರವು (ಚೇತನ), (ಅ)ಧೃತಿ. ಇದು ಕೃಷ್ಣನ\nಕ್ಷೇತ್ರ ಮತ್ತು ಅದರ ವಿಕಾರದ ಸೂತ್ರ ರೂಪದ ವಿವರಣೆ. ಈ ವಿಚಾರವನ್ನು ಎಷ್ಟು ವಿಸ್ತಾರವಾಗಿ ಬೇಕಾದರೂ\nನಾವು ವಿಶ್ಲೇಷಿಸಬಹುದು. ಕೃಷ್ಣ ಇಲ್ಲಿ ಎಲ್ಲವನ್ನು ಅಡಕವಾಗಿ ವಿವರಿಸಿದ್ದಾನೆ.\n\nಜ್ಞಾನದ ದಾರಿಯಲ್ಲಿ ಸಾಗಬೇಕಿದ್ದರೆ ನಮ್ಮ ನಡತೆಯಲ್ಲಿ ನಾವು ಅನುಸರಿಸಬೇಕಾದ ಕೆಲವು ನೀತಿ\nಸಂಹಿತೆಗಳಿವೆ. ಅದನ್ನು ನಾವು ಅನುಸರಿಸಬೇಕು. ನಾವು ನಮ್ಮ ಜೀವನದಲ್ಲಿ\nಅನುಸರಿಸಬೇಕಾದ ಇಪ್ಪತ್ತು ಗುಣ(twenty virtues)ಗಳನ್ನು ಕೃಷ್ಣ ಮುಂದಿನ ಐದು ಶ್ಲೋಕಗಳಲ್ಲಿ ವಿವರಿಸುತ್ತಾನೆ. ಈ\nಗುಣಗಳಲ್ಲಿ ಪ್ರತಿಯೊಂದನ್ನು ನಮ್ಮ ಜೀವನದಲ್ಲಿ ಎಷ್ಟು ಹೆಚ್ಚು ಅಳವಡಿಸಿಕೊಂಡೆವೋ ಅಷ್ಟು ನಾವು ಜ್ಞಾನ\nದಾರಿಯಲ್ಲಿ ಸಾಗಬಹುದು. ಇಲ್ಲದಿದ್ದರೆ ನಾವು ಅಜ್ಞಾನದ ದಾರಿಯಲ್ಲಿ ಸಾಗಬೇಕಾಗುತ್ತದೆ ಎನ್ನು ವ ಎಚ್ಚ ರವನ್ನು\nಕೂಡಾ ಕೃಷ್ಣ ಇಲ್ಲಿ ಕೊಟ್ಟಿದ್ದಾನೆ.\n\nಅಮಾನಿತ್ವಮಡಂಭಿತ್ವಮಹಿಂಸಾ ಕ್ಷಾಂತಿರಾರ್ಜವಮ್‌ ।\n\nಆಚಾರ್ಯೋಪಾಸನಂ ಶೌಚಂ ಸ್ಫೈರ್ಯಮಾತ್ಮವಿನಿಗ್ರಹಃ 1೭॥\n\nಅಮಾನಿತ್ವಮ್‌ ಅಡಂಭಿತ್ವಮ್‌ ಅಹಿಂಸಾ ಕ್ಷಾಂತಿಃ ಆರ್ಜವಮ್‌ ।\n\nಆಚಾರ್ಯ ಉಪಾಸನಮ್‌ ಶೌಚಮ್‌ ಸ್ಫೈರ್ಯಮ್‌ ಆತ್ಮವಿನಿಗ್ರಹಃ-- - ಬಿಂಕ ತೊರೆಯುವುದು, ಹಿರಿತನದ\nಸೋಗು ಹಾಕದಿರುವುದು, ನೋಯಿಸದಿರುವುದು, ಸೈರಣೆ, ನೇರ ನಡೆ ನುಡಿ, ಗುರುಸೇವೆ, ಮೈಮನಗಳ ಮಡಿ,\nಕದಲದ ತೀರ್ಪು, ಬಗೆಯ ಬಿಗಿತ,\n\n(೧) ಅಮಾನಿತ್ವಮ್‌: ಜ್ಞಾನ ಗಳಿಸುವುದಕ್ಕಾಗಿ ನಾವು ಮಾನ-ಸಮ್ಮಾನದ ಬಯಕೆಯನ್ನು ಬಿಡಬೇಕು. ತನಗೆ\nಸನ್ಮಾನವಾಗಬೇಕು, ಪ್ರಶಸ್ತಿ ಸಿಗಬೇಕು ಎನ್ನುವ ನಿರೀಕ್ಷೆಯಲ್ಲಿರುವವರಿಗೆ ಎಂದೂ ಜ್ಞಾನ ಸಿದ್ಧಿಯಾಗದು.\nಅದಕ್ಕಾಗಿ ಪ್ರಚಾರಪ್ರಿಯತೆಯನ್ನು ನಾವು ಮೊದಲು ಬಿಡಬೇಕು. ಎಲ್ಲಾ ಪ್ರಚಾರಗಳಿಗೆ ತಿಲಾಂಜಲಿ ಕೊಟ್ಟು\nಜ್ಞಾನದ ಬೆನ್ನು ಹತ್ತು- ಆಗ ಜ್ಞಾನ ದಕ್ಕುತ್ತದೆ. ಯಾರಾದರೂ ನಿನ್ನನ್ನು ಮೆಚ್ಚಿಕೊಂಡರೆ ಅದು ಅವರ ದೊಡ್ಡಸ್ತಿಕೆ-\nಅಲ್ಲಿ ನಮ್ರತೆಯಿಂದಿರು.\n\n(೨) ಅಡಂಭಿತ್ವಮ್‌ : ಎಲ್ಲರ ಮುಂದೆ ಸಣ್ಣವನಾಗಿ ಬದುಕಲು ಕಲಿ. ದೊಡ್ಡಸ್ತಿಕೆಯ ಪ್ರದರ್ಶನ ಬೇಡ. ಜ್ಞಾನ\nಮಾರ್ಗದಲ್ಲಿ ಎಂದೂ ಪ್ರಾಮಾಣಿಕತೆಯಿಂದ ಅತ್ತ ಸರಿಯಬೇಡ. ಇಲ್ಲದ್ದನ್ನು ಇದೆ ಎಂದು ತೋರಿಸಲು\nಹೋಗಬೇಡ.\n\n(೩) ಅಹಿಂಸಾ : ಎಂದೂ ಇನ್ನೊಬ್ಬರನ್ನು ನೋಯಿಸಬೇಡ. ನಾವು ಇನ್ನೊಬ್ಬರ ಮನಸ್ಸನ್ನು ಘಾಸಿಗೊಳಿಸಿದರೆ\nಅದನ್ನು ಮರಳಿ ವಾಸಿ ಮಾಡುವ ಯಾವ ಔಷಧವೂ ಇಲ್ಲ. ಆದ್ದರಿಂದ ಎಂದೂ ಇನ್ನೊಬ್ಬರನ್ನು\nಮುಖಭಂಗ(face-saving) ಮಾಡಬೇಡ. ಇನ್ನೊ ಬ್ಬರಿಗೆ ತೊಂದರೆ ಕೊಡದೇ ಇರುವುದು ಅಹಿಂಸೆ.\n\n(೪) ಕ್ಷಾಂತಿಃ : ಪ್ರತೀಕಾರ ಮಾಡದೇ ಇರುವುದು. ಒಬ್ಬರು ನಮಗೆ ಕೇಡು ಬಗೆದಾಗ ನಾವು ಅದಕ್ಕೆ ಪ್ರತಿಕೇಡು\nಬಗೆಯಲು ಹೋಗಬಾರದು. ತಪ್ಪು ಮಾಡಿದವರಿಗೆ ಶಿಕ್ಷೆ ಕೊಡಲು ಒಂದು ವ್ಯವಸ್ಥೆ ಇದೆ. ಲೌಕಿಕವಾಗಿ\nನೋಡಿದರೆ, ಯಾರಾದರು ತಪ್ಪು ಮಾಡಿದಾಗ ಅವರಿಗೆ ಶಿಕ್ಷೆ ಕೊಡುವ ಜವಾಬ್ದಾರಿ ಆರಕ್ಷಕ ಮತ್ತು ನ್ಯಾಯಾಂಗ\nವ್ಯವಸ್ಥೆಯದೇ ಹೊರತು ನಮ್ಮದಲ್ಲ. ಒಂದು ವೇಳೆ ನಾವು ತಪ್ಪು ಮಾಡಿದವರಿಗೆ ಶಿಕ್ಷೆ ಕೊಡಲು ಹೊರಟರೆ ಅದು\nಕಾನೂನನ್ನು ಕೈಯಲ್ಲಿ ತೆಗೆದುಕೊಂಡ ಅಪರಾಧವಾಗುತ್ತದೆ. ಅದೇ ರೀತಿ ಭಗವಂತನ ರಾಜ್ಯದಲ್ಲಿ ತಪ್ಪು\nಮಾಡಿದವರಿಗೆ ಶಿಕ್ಷ ಕೊಡಲು ಪ್ರತ್ಯೇಕ ವ್ಯವಸ್ಥೆ ಇದೆ. ಆದ್ದರಿಂದ ನಿನಗೆ ಪ್ರತೀಕಾರ ತೆಗೆದುಕೊಳ್ಳುವುದಕ್ಕಾಗಲೀ\nಶಾಪ ಹಾಕುವುದಕ್ಕಾಗಲೀ ಹಕ್ಕಿಲ್ಲ.\n\nಈ ಮೇಲಿನ ಗುಣಗಳಿಗೆ ಉತ್ತಮ ದೃಷ್ಟಾಂತ ಜಡಭರತ ಮತ್ತು ರೈಕ್ವ ಮುನಿ. ಇವರ ಜೀವನ ಚರಿತ್ರೆಯನ್ನು\nಓದಿದರೆ ಅವರು ಈ ಗುಣವನ್ನು ತಮ್ಮ ಜೀವನದಲ್ಲಿ ಹೇಗೆ ಪಾಲಿಸಿದ್ದರು ಎನ್ನುವುದು ತಿಳಿಯುತ್ತದೆ.\n\n(೫) ಆರ್ಜವಮ್‌ : ಮುಖವಾಡವಿಲ್ಲದ ಬದುಕು. ನೇರ ನಡೆ ನುಡಿ. ಒಳಗೊಂದು ಹೊರಗೊಂದು ಇಲ್ಲದ\nಪ್ರಾಮಾಣಿಕ ಬದುಕು(honest life).\n\n(೬) ಆಚಾರ್ಯೋಪಾಸನಮ್‌: ಆಚಾರ್ಯ ಎಂದರೆ ಯಾವುದು ಸರಿ ಯಾವುದು ತಪ್ಪು ಎಂದು ಚೆನ್ನಾಗಿ ತಿಳಿದು\nಅದನ್ನು ಆಚರಣೆಗೆ ತರುವವರು. ತಾವು ಸತ್ಯವನ್ನು ಕಂಡು, ಸಮಾಜದ ಮುಂದೆ ಅದನ್ನು ನಡೆದು\nತೋರಿಸುವವರು. ಅಂಥವರ ಸೇವೆ. ಮಾಡು. ಜ್ಞಾನಿಗಳು ಸುಲಭವಾಗಿ ಸಿಗುವುದಿಲ್ಲ ಮತ್ತು ಅವರು\nಸಾಮಾನ್ಯವಾಗಿ ಪರೀಕ್ಷಿಸದೆ ಜ್ಞಾನ ಧಾರೆ ಮಾಡುವುದಿಲ್ಲ. ಏನೇ ಆದರೂ ಜ್ಞಾನಿಗಳ ಬೆನ್ನುಬಿಡಬೇಡ.\nನಿನ್ನಲ್ಲಿರುವ ಜ್ಞಾನ ತೃಷೆ ಗಾಢವಾಗಿದ್ದಲ್ಲಿ ಖಂಡಿತವಾಗಿ ಅವರು ಜ್ಞಾನ ಧಾರೆ ಮಾಡುತ್ತಾರೆ. ಜ್ಞಾನ ಬೇಕಿದ್ದರೆ\nಜ್ಞಾನಿಗಳು ತೆರೆದುಕೊಳ್ಳುವ ತನಕ ಕಾಯಬೇಕು. ಇದಕ್ಕೆ ಉತ್ತಮ ದೃಷ್ಟಾಂತ ಶ್ವೇತಕೇತು ಮತ್ತು\nಪ್ರಶ್ನೋಪನಿಷತ್ತಿನಲ್ಲಿ ಬರುವ ಪಿಪ್ಪಲಾದರ ಕಥೆ.\n\n(೭) ಶೌಚಮ್‌: ಶೌಚ ಎಂದರೆ ಶುಚಿತ್ವ. ಈ ವಿಷಯವನ್ನು ಹಿಂದಿನ ಅಧ್ಯಾಯದಲ್ಲಿ ಸ್ವಲ್ಪ ಮಟ್ಟಿಗೆ ನೋಡಿದ್ದೇವೆ.\nಕನ್ನಡದಲ್ಲಿ ಶೌಚಮ್‌ ಎಂದರೆ 'ಮಡಿ'. ನಾವು ಮಡಿ ಮಾಡುವುದನ್ನು ಬಿಟ್ಟು ಮಡಿಯಾಗುವುದನ್ನು ಕಲಿಯಬೇಕು.\n\nಸ್ನಾನ ಮಾಡಿ ಒದ್ದೆ ಬಟ್ಟೆ ಉಟ್ಟು ಯಾರನ್ನೂ ಮುಟ್ಟದೆ ಇದ್ದರೆ ಮಡಿಯಾಗಲು ಸಾಧ್ಯವಿಲ್ಲ. ಶುಚಿ ಎನ್ನುವುದು\nಮೂಲಭೂತವಾಗಿ ಮನಸ್ಸಿಗೆ ಸಂಬಂಧಪಟ್ಟದ್ದು. ಅದಕ್ಕೆ ಪೂರಕವಾಗಿ ದೇಹ ಶುದ್ಧಿ. ಪ್ರಾಪಂಚಿಕ ವಿಚಾರವನ್ನು\nಮರೆತು, ಮನಸ್ಸನ್ನು ಭಗವಂತನಲ್ಲಿ ನೆಲೆ ನಿಲ್ಲಿಸುವುದು ಮಡಿ. ನಾವು. ಕಾಯಾ-ವಾಚಾ-ಮನಸಾ\nಮಡಿಯಾಗಬೇಕು. ನಮ್ಮಲ್ಲಿ ಕೆಟ್ಟ ಯೋಚನೆ ಬಂದರೆ, ಕೆಟ್ಟ ಮಾತು ಬಾಯಲ್ಲಿ ಬಂದರೆ- ಆಗ ನಾವು ಮೈಲಿಗೆ.\nನಿಜವಾಗಿ ಕಾಯ-ವಾಚಾ-ಮನಸಾ ಮಡಿಯಾಗಿರುವವ ಮೈಲಿಗೆಯವರೊಂದಿಗಿದ್ದರೆ ಜೊತೆಗಿರುವವರೆಲ್ಲರೂ\nಮಡಿಯಾಗಬಹುದು. ಇದನ್ನೇ ಹಿಂದೆ “ಪಂಕ್ಷಿಪಾವನ' ಎಂದು ಕರೆಯುತ್ತಿದ್ದರು. ಪೂರ್ಣ ಮಡಿಯಾಗಿರುವವ\nಯಾವ ಪಂಕ್ತಿಯಲ್ಲಿ ಕುಳಿತನೋ ಆ ಪಂಕ್ತಿ ಮಡಿ. ಶಾಸ್ತ್ರ ಜ್ಞಾನವಿಲ್ಲದ ಮಡಿ ಮಡಿಯಲ್ಲ. ದೇವರ ಸ್ಮರಣೆ\nಮನಸ್ಸಿ ನಲ್ಲಿ, ದೇವರ ನಾಮ ಬಾಯಿಯಲ್ಲಿ ಇದ್ದಾಗ ನಾವು ಮಡಿ.\n\nಮನಸ್ಸನ್ನು ಶುದ್ಧ ಮಾಡುವುದಕ್ಕೋಸ್ಕರ ಆಚಮನ ಮತ್ತು ಪ್ರಾಣಾಯಾಮ. “ಓ ಭಗವಂತಾ, ನಿನ್ನ\nಕಾರುಣ್ಯಧಾರೆಯಿಂದ ನನ್ನ ಸಹಸ್ರಾರದಿಂದ ಅಮೃತವನ್ನು ಕೆಳಕ್ಕೆ ಇಳಿಸಿ, ನನ್ನ ಇಡೀ ಮೈ ಪಾವನವಾಗುವಂತೆ\nಮಾಡು, ನನ್ನೊಳಗಿನ ಎಲ್ಲಾ ಪಾಪಗಳೂ ಕೊಳೆಗಳೂ ಸುಟ್ಟು ತೊಳೆದುಹೋಗಲಿ” ಎನ್ನುವ\nಅನುಸಂಧಾನದಿಂದ, ಧ್ಯಾನಪೂರ್ವಕ ಪಾಪಪುರುಷ ನಿರಸನ ಮಾಡಬೇಕು. ಇಲ್ಲಿ ನಮ್ಮ ತಲೆಯಿಂದ\nಅಮೃತಧಾರೆ ಇಳಿದು ಬರುವುದನ್ನು ನಾವು ಅನುಭವಿಸಬೇಕು ಸ್ಥೈರ್ಯಮ್‌ : ಮನಸ್ಸಿನ ಸ್ಥಿರತೆ(Steadfastness) ಸ್ಥೈರ್ಯ. ನಮಗೆ ನಮ್ಮದೇ ಆದ ಸ್ವಂತ ನಿರ್ಧಾರ ಬೇಕು.\nಯಾರೋ ಹೇಳಿದಂತೆ ನಾವು ನಮ್ಮ ನಿರ್ಧಾರವನ್ನು ಬದಲಿಸಿಕೊಳ್ಳುತ್ತಾ ಗೊಂದಲಕ್ಕೊಳಗಾಗಬಾರದು. ನಾವು\nನಮ್ಮ ತಲೆಯಲ್ಲಿ ಚಿಂತಿಸಬಲ್ಲವರಾಗಬೇಕು. ನಮಗೆ ಯಾವುದಾದರೂ ಪ್ರಶ್ನೆ ಬಂದರೆ ಅದಕ್ಕೆ ಉತ್ತರವನ್ನು\nಕಂಡುಕೊಳ್ಳುವ ಸಾಮರ್ಥ್ಯ ನಮ್ಮ ತಲೆಯಲ್ಲೇ ಇರುತ್ತದೆ. “ಎಲ್ಲಿ ಪ್ರಶ್ನೆ ಇದೆಯೋ ಅಲ್ಲೇ ಉತ್ತರವೂ ಇರುತ್ತದೆ”.\nಶಾಸ್ತ್ರವನ್ನು ಚೆನ್ನಾಗಿ ಅಧ್ಯಾಯನ ಮಾಡಿ ನೀನೇ ನಿನ್ನ ಸಮಸ್ಯೆಗೆ ಉತ್ತರ ಕಂಡುಕೊಂಡು ದೃಢವಾಗಿ ಕೆಲಸ\nಮಾಡು. ಯಾರ ಯಾರೋ ಮಾತನ್ನು ಕೇಳಿ ಗೊಂದಲಗೊಳ್ಳದೆ ಸ್ಥೈರ್ಯವನ್ನು ಸಾಧಿಸು.\n\n(೯) ಆತ್ಮವಿನಿಗ್ರಹಃ : ಇಂದ್ರಿಯ ನಿಯಂತ್ರಣ (self control). ನಮ್ಮ ಇಂದ್ರಿಯ ನಮ್ಮ ಹಿಡಿತದಲ್ಲಿರಬೇಕು.\nಇಂದ್ರಿಯ ಹಿಡಿತಲ್ಲಿರಬೇಕಾದರೆ ನಾವು ನಮ್ಮ ಮನಸ್ಸನ್ನು ಹಿಡಿತದಲ್ಲಿಟ್ಟುಕೊಳ್ಳಬೇಕು. ಮನಸ್ಸಿನ ಕೈಯಲ್ಲಿ\nನೀನು ಮಂಗನಾಗಬೇಡ, ಮನಸ್ಸನ್ನು ನೀನು ನಿಯಂತ್ರಿಸು. ಇದಕ್ಕಾಗಿ ನಿನ್ನ ಮನಸ್ಸನ್ನು ದೇವರಲ್ಲಿ ನೆಲೆ\nನಿಲ್ಲಿಸು. ಹೀಗೆ ಮನೋನಿಗ್ರಹದಿಂದ ಇಂದ್ರಿಯ ನಿಗ್ರಹ ಸಾಧಿಸು.",
  "13.7": "ಇಚ್ಛಾ ದ್ವೇಷಃ ಸುಖಂ ದುಃಖಂ ಸಂಘಾತಃ ಚೇತನಾ ಧೃತಿಃ |\n\nಏತತ್‌ ಕ್ಷೇತ್ರಂ ಸಮಾಸೇನ ಸವಿಕಾರಮ್‌ ಉದಾಹೃತಮ್‌ -- ಮಣ್ಣು[ಪೃಥಿವಿ], ನೀರು[ವರುಣ], ಬೆಂಕಿ[ಅಗ್ನಿ 1:\nಗಾಳ್ವ[ವಾಯುಪುತ್ರ ಮರೀಚಿ], ಬಾನು[ಅವಕಾಶ ದೇವತೆ, ವಿಘ್ನ ನಾಶ-ವಿನಾಯಕ-ಗಣಪತಿ]-ಎಂಬ ಐದು\nಮಹಾಭೂತಗಳು. ಅಹಂಕಾರತತ್ವ [್ರಹ್ಮವಾಯು ಮತ್ತು ಶಿವ], ಬುದ್ಧಿತತ್ವ[ಪಾರ್ವತಿ], ಮೂಲಪ್ರಕೃತಿ[ಶ್ರಿ,,\nಕಿವ[ಚಂದ್ರ।೦,, ತೊಗಲು[ವಾಯುಪುತ್ರ ಮರುತ್‌], ಕಣ್ಣು[ಸೂರ್ಯ], ನಾಲಿಗೆ(ವರುಣ], ಮೂಗು[ಅಶ್ವಿಗಳು],\nಬಾಯಿ [ಅಗ್ನಿ], ಕೈಗಳು[ವಾಯುಪುತ್ರರಿಬ್ಬ ರು], ಕಾಲುಗಳು[ಇಂದ್ರ ಪುತ್ರರಾದ ಯಜ್ಞ(ಜಯತ) ಮತ್ತು ಶಂಭು],\nಪಾಯು[ಯಮ], ಉಪಸ್ಥ[ಲಿಂಗ ದೇವತೆ ಶಿವ-ಗಂಡಸರಲ್ಲಿ ; ಸ್ವಾಯಂಭುವಮನು-ಸ್ತ್ರೀಯರಲ್ಲಿ] ಹೀಗೆ ಹತ್ತು\nಇಂದ್ರಿಯಗಳು. ಹನ್ನೊಂದನೆಯದು ಮನಸ್ತತ್ವ[ಇಂದ್ರ, ಕಾಮ ಮತ್ತು ಅನಿರುದ್ಧ] ಮತ್ತು ಐದು ಜ್ಞಾನೇಂದ್ರಿಯ\nವಿಷಯಗಳು: ಶಬ್ಧ, ಸ್ಪರ್ಶ, ರೂಪ, ರಸ ಮತ್ತು ಗಂಧ[ರುದ್ರ ಪುತ್ರರಾದ ಪ್ರಾಣ, ಅಪಾನ, ವ್ಯಾನ, ಉದಾನ\nಮತ್ತು ಸಮಾನ]ಇವು ೨೪ ಅಡಕವಾಗಿ ಕ್ಷೇತ್ರಗಳು.\n\nಬಯಕೆ[ಶ್ರೀ ಮತ್ತು ಭಾರತಿ], ದ್ವೇಷ[(ದ್ವಾಪರ-ಶಕುನಿ], ಸುಖ[ಮುಖ್ಯಪ್ರಾಣ-ವಾಯು-ಭೀಮ], ದುಃಖ[ಕಲಿ-\nದುರ್ಯೋಧನ], ಸಮಷ್ಟಿಶರೀರ[ಶರೀರದಲ್ಲಿರುವ ಅಭಿಮಾನಿ ಜೀವ; ಸಮಸ್ತ ಅಭಿಮಾನಿ ದೇವತೆಗಳು],\nನೆನಪಿನ ಹರಹು[ಶ್ರೀ], ಧೈರ್ಯ[ಸರಸ್ವತಿ ಮತ್ತು ಭಾರತಿ] ಇವು ಏಳು ವಿಶೇಷ ಕ್ರಿಯೆಗಳಾದ ವಿಕಾರಗಳು. ಹೀಗೆ\nವಿಕಾರಗಳ ಜೊತೆಗೆ ಕ್ಷೇತ್ರವನ್ನು ಅಡಕವಾಗಿ ಹೇಳಿದ್ದಾಯಿತು.\n\nಈ ಎರಡು ಶ್ಲೋಕಗಳಲ್ಲಿ ಕೃಷ್ಣ ಕ್ಷೇತ್ರ ಮತ್ತು ಕ್ಷೇತ್ರದ ವಿಕಾರವನ್ನು ವಿವರಿಸಿದ್ದಾನೆ. ಕ್ಷೇತ್ರ ಎನ್ನುವ ಅಖಂಡ\nಘಟಕದೊಳಗೆ ಇರುವ ಜಗತ್ತಿನ ಘಟಕಾಂಶಗಳನ್ನು ಕೃಷ್ಣ ಇಲ್ಲಿ ಸೂತ್ರ ರೂಪದಲ್ಲಿ ಅಡಕವಾಗಿ ವಿವರಿಸಿದ್ದಾನೆ.\nಮೊದಲನೆಯದಾಗಿ. ಪಂಚಮಹಾಭೂತಗಳು. ಈ ಐದರಿಂದ ಈ ಪಿಂಡಾಂಡ ಮತ್ತು ಬ್ರಹ್ಮಾಂಡ\nನಿರ್ಮಾಣವಾಗಿದೆ. ಈ ಕಾರಣಕ್ಕಾಗಿ ಬ್ರಹ್ಮಾಂಡವನ್ನು 'ಪ್ರ-ಪಂಚ' ಎಂದು ಕರೆಯುತ್ತಾರೆ. ಈ ಪಂಚ\nಮಹಾಭೂತಗಳೇ ಪ್ರಪಂಚದ ಮೂಲದ್ರವ್ಯ. ಪಿಂಡಾಂಡದಲ್ಲಿ ಈ ಪಂಚ ಮಹಾಭೂತಗಳನ್ನು ಅನ್ನಮಯ ಮತ್ತು\nಪ್ರಾಣಮಯ ಎಂದು ಕರೆಯತ್ತಾರೆ. ಕಾಣುವ ಸ್ಥೂಲ ಶರೀರ ಪ್ರಥಿವಿ ಮತ್ತು ನೀರಿನ ಭಾಗದಿಂದಾಗಿದೆ. ಇಂತಹ\nಸ್ಥೂಲ ಶರೀರದೊಳಗೆ ಕಾಣದ ಪ್ರಾಣಮಯಕೋಶವಿದೆ. ದೇಹದ ಶಾಖ(ಬೆಂಕಿ), ಉಸಿರಾಟ(ಗಾಳಿ) ಮತ್ತು\nಒಳಗೆ ರಕ್ತ-ಗಾಳಿ ಸಂಚಾರದ ಅವಕಾಶ(ಆಕಾಶ). ಇದರಿಂದಾಚೆಗೆ ಮನಸ್ಸು ಮತ್ತು ಬುದ್ಧಿಯನ್ನೂಳಗೊಂಡ\nಮನೋಮಯಕೋಶ, ಅದರಿಂದಾಚೆಗೆ ವಿಜ್ಞಾನಮಯಕೋಶ-ಸ್ಮರಣಶಕ್ತಿ. ಆದ್ದರಿಂದ ಬುದ್ದಿಗೆ ಮೊದಲು\nಅಹಂಕಾರ ಮತ್ತು ಚಿತ್ತ. ಇಲ್ಲಿ ಅಹಂಕಾರ ಅಂದರೆ “ನನ್ನ ಅಸ್ತಿತ್ವದ ಅರಿವು(awareness of self). ಈ\nಅಹಂಕಾರ ತತ್ವ ಪಿಂಡಾಂಡದಲ್ಲಿ ಚಿತ್ತ, ಬ್ರಹ್ಮಾಂಡದಲ್ಲಿ ಮಹತತ್ವ.\n\nವ್ಯಕ್ತವಾಗುವ ಈ ಪ್ರಪಂಚದ ಮೂಲ ಅವ್ಯಕ್ತ. ಸೃಷ್ಟಿಯ ಮೂಲಸ್ಥಿತಿ-ಪ್ರಳಯಸಾಗರ. ಅಂದರೆ\nಪರಮಾಣುರೂಪದಲ್ಲಿ ಚದುರಿಕೊಂಡಿರುವ ಅವ್ಯಕ್ತ ಪ್ರಪಂಚ. ಇಂತಹ ಪ್ರಪಂಚದಲ್ಲಿ ಚತುರ್ಮುಖ\nಮಹತತ್ವವನ್ನು ಸೃಷ್ಟಿ ಮಾಡಿದ. ಪ್ರಳಯ ಸಾಗರದಲ್ಲಿ ತನ್ನ ಅಸ್ತಿತ್ವದ ಅರಿವಿಲ್ಲದೇ ಇದ್ದ ಜೀವಗಳಿಗೆ “ನಾನು'\nಎನ್ನುವ ಅರಿವು ಬರುವುದೇ ಮಹತತ್ವದ ಸೃಷ್ಟಿ. ಚಿತ್ತದ ವ್ಯಾಪ್ತಿ ಚೇತನ. ಇದು ನಮ್ಮ ನೆನಪಿನ ವಿಸ್ತಾರ.\n\nಈ ಶರೀರದಲ್ಲಿ ಐದು ಜ್ಞಾನೇಂದ್ರಿಯಗಳು, ಐದು. ಕರ್ಮೇಂದ್ರಿಯಗಳಿವೆ. ಮತ್ತು ಹನ್ನೊಂದನೇ\nಇಂದ್ರಿಯವಾಗಿರುವುದು ಮನಸ್ಸು. ಕಿವಿಯಿಂದ ಶಬ್ದಗ್ರಹಣ, ಕಣ್ಣಿನಿಂದ ರೂಪ ಗ್ರಹಣ, ಮೂಗಿನಿಂದ ಗಂಧ\nಗ್ರಹಣ, ನಾಲಿಗೆಯಿಂದ ರಸ ಗ್ರಹಣ, ತೊಗಲಿನಿಂದ ಗಾಳಿಯ ಗ್ರಹಣ. ಅದೇ ರೀತಿ ಬಾಯಿ ಮಾತನಾಡಲು, ಕೈ\nಕೆಲಸ ಮಾಡಲು, ಕಾಲು ನಡೆಯಲು. ಈ ಎಂಟನ್ನು ಗ್ರಹ(sense organs)ಗಳೆನ್ನುತ್ತಾರೆ. ನಂತರ ಪಾಯು ಮತ್ತು\nಉಪಸ್ಥ(ವಿಸರ್ಜನಾಂಗ ಮತ್ತು ಸಂತಾನವೃದ್ಧಿ)ಗಳು. ಈ ಎಲ್ಲವನ್ನು ಚಿಂತನೆಗೊಳಪಡಿಸುವ ಹನ್ನೊಂದನೇ\nಇಂದ್ರಿಯ ಮನಸ್ಸು. ಇವೆಲ್ಲವೂ ಕ್ಷೇತ್ರದ ಘಟಕಾಂಶಗಳು. ಸಮಷ್ಟಿಯಾಗಿ ಇದು ಕ್ಷೇತ್ರ. [ಇಲ್ಲಿ ಹೇಳಿರುವ\nಪ್ರತಿಯೊಂದು ಘಟಕದೊಂದಿಗೆ ಅದರ ಅಭಿಮಾನಿ ದೇವತೆಯರೂ ಸೇರಿದ್ದಾರೆ. ಅದನ್ನು ಮೇಲೆ ಸಂಕ್ಷಿಪ್ತವಾಗಿ\nಹೇಳಲಾಗಿದೆ]\n\nಈ ಜಗತ್ತು ಸದಾ ಬದಲಾಗುತ್ತಿರುತ್ತದೆ. ಅದಕ್ಕಾಗಿ ಜಗತ್ತನ್ನು ಅಶ್ವತ್ಥ ಎಂತಲೂ ಕರೆಯುತ್ತಾರೆ. ಅಶ್ವ ನಿರಂತರ\nಚಲನೆಯಲ್ಲಿರುವ ಪ್ರಾಣಿ. ಅದು ನಿಶ್ಚಲವಾಗಿ ಇರುವುದೇ ಇಲ್ಲ. ಈ ಪ್ರಪಂಚ ಕೂಡಾ ಹಾಗೆ ಸದಾ\nಚಲನೆಯಲ್ಲಿರುವುದರಿಂದ-ಅದನ್ನು ಪ್ರಾಚೀನರು ಅಶ್ವತ್ಥ ಎಂದು ಕರೆದರು. ನಮ್ಮ ದೇಹ ಅನ್ನುವುದು ಭೌತಿಕ\nವಿಕಾರ. ಅದರಲ್ಲಿ ಆಗತಕ್ಕಂತಹ ಮಾನಸಿಕ ಪ್ರಪಂಚದ ಎಲ್ಲಾ ತೊಳಲಾಟ ಮಾನಸಿಕ ವಿಕಾರ. ವಿಶೇಷವಾಗಿ\nನಮ್ಮ ಇಚ್ಛೆ(ಬಯಕೆ), (ಅ)ದ್ವೇಷ, ಸುಖ-ದುಃಖ, ನಮ್ಮ ನೆನಪಿನ ಹರವು (ಚೇತನ), (ಅ)ಧೃತಿ. ಇದು ಕೃಷ್ಣನ\nಕ್ಷೇತ್ರ ಮತ್ತು ಅದರ ವಿಕಾರದ ಸೂತ್ರ ರೂಪದ ವಿವರಣೆ. ಈ ವಿಚಾರವನ್ನು ಎಷ್ಟು ವಿಸ್ತಾರವಾಗಿ ಬೇಕಾದರೂ\nನಾವು ವಿಶ್ಲೇಷಿಸಬಹುದು. ಕೃಷ್ಣ ಇಲ್ಲಿ ಎಲ್ಲವನ್ನು ಅಡಕವಾಗಿ ವಿವರಿಸಿದ್ದಾನೆ.\n\nಜ್ಞಾನದ ದಾರಿಯಲ್ಲಿ ಸಾಗಬೇಕಿದ್ದರೆ ನಮ್ಮ ನಡತೆಯಲ್ಲಿ ನಾವು ಅನುಸರಿಸಬೇಕಾದ ಕೆಲವು ನೀತಿ\nಸಂಹಿತೆಗಳಿವೆ. ಅದನ್ನು ನಾವು ಅನುಸರಿಸಬೇಕು. ನಾವು ನಮ್ಮ ಜೀವನದಲ್ಲಿ\nಅನುಸರಿಸಬೇಕಾದ ಇಪ್ಪತ್ತು ಗುಣ(twenty virtues)ಗಳನ್ನು ಕೃಷ್ಣ ಮುಂದಿನ ಐದು ಶ್ಲೋಕಗಳಲ್ಲಿ ವಿವರಿಸುತ್ತಾನೆ. ಈ\nಗುಣಗಳಲ್ಲಿ ಪ್ರತಿಯೊಂದನ್ನು ನಮ್ಮ ಜೀವನದಲ್ಲಿ ಎಷ್ಟು ಹೆಚ್ಚು ಅಳವಡಿಸಿಕೊಂಡೆವೋ ಅಷ್ಟು ನಾವು ಜ್ಞಾನ\nದಾರಿಯಲ್ಲಿ ಸಾಗಬಹುದು. ಇಲ್ಲದಿದ್ದರೆ ನಾವು ಅಜ್ಞಾನದ ದಾರಿಯಲ್ಲಿ ಸಾಗಬೇಕಾಗುತ್ತದೆ ಎನ್ನು ವ ಎಚ್ಚ ರವನ್ನು\nಕೂಡಾ ಕೃಷ್ಣ ಇಲ್ಲಿ ಕೊಟ್ಟಿದ್ದಾನೆ.\n\nಅಮಾನಿತ್ವಮಡಂಭಿತ್ವಮಹಿಂಸಾ ಕ್ಷಾಂತಿರಾರ್ಜವಮ್‌ ।\n\nಆಚಾರ್ಯೋಪಾಸನಂ ಶೌಚಂ ಸ್ಫೈರ್ಯಮಾತ್ಮವಿನಿಗ್ರಹಃ 1೭॥\n\nಅಮಾನಿತ್ವಮ್‌ ಅಡಂಭಿತ್ವಮ್‌ ಅಹಿಂಸಾ ಕ್ಷಾಂತಿಃ ಆರ್ಜವಮ್‌ ।\n\nಆಚಾರ್ಯ ಉಪಾಸನಮ್‌ ಶೌಚಮ್‌ ಸ್ಫೈರ್ಯಮ್‌ ಆತ್ಮವಿನಿಗ್ರಹಃ-- - ಬಿಂಕ ತೊರೆಯುವುದು, ಹಿರಿತನದ\nಸೋಗು ಹಾಕದಿರುವುದು, ನೋಯಿಸದಿರುವುದು, ಸೈರಣೆ, ನೇರ ನಡೆ ನುಡಿ, ಗುರುಸೇವೆ, ಮೈಮನಗಳ ಮಡಿ,\nಕದಲದ ತೀರ್ಪು, ಬಗೆಯ ಬಿಗಿತ,\n\n(೧) ಅಮಾನಿತ್ವಮ್‌: ಜ್ಞಾನ ಗಳಿಸುವುದಕ್ಕಾಗಿ ನಾವು ಮಾನ-ಸಮ್ಮಾನದ ಬಯಕೆಯನ್ನು ಬಿಡಬೇಕು. ತನಗೆ\nಸನ್ಮಾನವಾಗಬೇಕು, ಪ್ರಶಸ್ತಿ ಸಿಗಬೇಕು ಎನ್ನುವ ನಿರೀಕ್ಷೆಯಲ್ಲಿರುವವರಿಗೆ ಎಂದೂ ಜ್ಞಾನ ಸಿದ್ಧಿಯಾಗದು.\nಅದಕ್ಕಾಗಿ ಪ್ರಚಾರಪ್ರಿಯತೆಯನ್ನು ನಾವು ಮೊದಲು ಬಿಡಬೇಕು. ಎಲ್ಲಾ ಪ್ರಚಾರಗಳಿಗೆ ತಿಲಾಂಜಲಿ ಕೊಟ್ಟು\nಜ್ಞಾನದ ಬೆನ್ನು ಹತ್ತು- ಆಗ ಜ್ಞಾನ ದಕ್ಕುತ್ತದೆ. ಯಾರಾದರೂ ನಿನ್ನನ್ನು ಮೆಚ್ಚಿಕೊಂಡರೆ ಅದು ಅವರ ದೊಡ್ಡಸ್ತಿಕೆ-\nಅಲ್ಲಿ ನಮ್ರತೆಯಿಂದಿರು.\n\n(೨) ಅಡಂಭಿತ್ವಮ್‌ : ಎಲ್ಲರ ಮುಂದೆ ಸಣ್ಣವನಾಗಿ ಬದುಕಲು ಕಲಿ. ದೊಡ್ಡಸ್ತಿಕೆಯ ಪ್ರದರ್ಶನ ಬೇಡ. ಜ್ಞಾನ\nಮಾರ್ಗದಲ್ಲಿ ಎಂದೂ ಪ್ರಾಮಾಣಿಕತೆಯಿಂದ ಅತ್ತ ಸರಿಯಬೇಡ. ಇಲ್ಲದ್ದನ್ನು ಇದೆ ಎಂದು ತೋರಿಸಲು\nಹೋಗಬೇಡ.\n\n(೩) ಅಹಿಂಸಾ : ಎಂದೂ ಇನ್ನೊಬ್ಬರನ್ನು ನೋಯಿಸಬೇಡ. ನಾವು ಇನ್ನೊಬ್ಬರ ಮನಸ್ಸನ್ನು ಘಾಸಿಗೊಳಿಸಿದರೆ\nಅದನ್ನು ಮರಳಿ ವಾಸಿ ಮಾಡುವ ಯಾವ ಔಷಧವೂ ಇಲ್ಲ. ಆದ್ದರಿಂದ ಎಂದೂ ಇನ್ನೊಬ್ಬರನ್ನು\nಮುಖಭಂಗ(face-saving) ಮಾಡಬೇಡ. ಇನ್ನೊ ಬ್ಬರಿಗೆ ತೊಂದರೆ ಕೊಡದೇ ಇರುವುದು ಅಹಿಂಸೆ.\n\n(೪) ಕ್ಷಾಂತಿಃ : ಪ್ರತೀಕಾರ ಮಾಡದೇ ಇರುವುದು. ಒಬ್ಬರು ನಮಗೆ ಕೇಡು ಬಗೆದಾಗ ನಾವು ಅದಕ್ಕೆ ಪ್ರತಿಕೇಡು\nಬಗೆಯಲು ಹೋಗಬಾರದು. ತಪ್ಪು ಮಾಡಿದವರಿಗೆ ಶಿಕ್ಷೆ ಕೊಡಲು ಒಂದು ವ್ಯವಸ್ಥೆ ಇದೆ. ಲೌಕಿಕವಾಗಿ\nನೋಡಿದರೆ, ಯಾರಾದರು ತಪ್ಪು ಮಾಡಿದಾಗ ಅವರಿಗೆ ಶಿಕ್ಷೆ ಕೊಡುವ ಜವಾಬ್ದಾರಿ ಆರಕ್ಷಕ ಮತ್ತು ನ್ಯಾಯಾಂಗ\nವ್ಯವಸ್ಥೆಯದೇ ಹೊರತು ನಮ್ಮದಲ್ಲ. ಒಂದು ವೇಳೆ ನಾವು ತಪ್ಪು ಮಾಡಿದವರಿಗೆ ಶಿಕ್ಷೆ ಕೊಡಲು ಹೊರಟರೆ ಅದು\nಕಾನೂನನ್ನು ಕೈಯಲ್ಲಿ ತೆಗೆದುಕೊಂಡ ಅಪರಾಧವಾಗುತ್ತದೆ. ಅದೇ ರೀತಿ ಭಗವಂತನ ರಾಜ್ಯದಲ್ಲಿ ತಪ್ಪು\nಮಾಡಿದವರಿಗೆ ಶಿಕ್ಷ ಕೊಡಲು ಪ್ರತ್ಯೇಕ ವ್ಯವಸ್ಥೆ ಇದೆ. ಆದ್ದರಿಂದ ನಿನಗೆ ಪ್ರತೀಕಾರ ತೆಗೆದುಕೊಳ್ಳುವುದಕ್ಕಾಗಲೀ\nಶಾಪ ಹಾಕುವುದಕ್ಕಾಗಲೀ ಹಕ್ಕಿಲ್ಲ.\n\nಈ ಮೇಲಿನ ಗುಣಗಳಿಗೆ ಉತ್ತಮ ದೃಷ್ಟಾಂತ ಜಡಭರತ ಮತ್ತು ರೈಕ್ವ ಮುನಿ. ಇವರ ಜೀವನ ಚರಿತ್ರೆಯನ್ನು\nಓದಿದರೆ ಅವರು ಈ ಗುಣವನ್ನು ತಮ್ಮ ಜೀವನದಲ್ಲಿ ಹೇಗೆ ಪಾಲಿಸಿದ್ದರು ಎನ್ನುವುದು ತಿಳಿಯುತ್ತದೆ.\n\n(೫) ಆರ್ಜವಮ್‌ : ಮುಖವಾಡವಿಲ್ಲದ ಬದುಕು. ನೇರ ನಡೆ ನುಡಿ. ಒಳಗೊಂದು ಹೊರಗೊಂದು ಇಲ್ಲದ\nಪ್ರಾಮಾಣಿಕ ಬದುಕು(honest life).\n\n(೬) ಆಚಾರ್ಯೋಪಾಸನಮ್‌: ಆಚಾರ್ಯ ಎಂದರೆ ಯಾವುದು ಸರಿ ಯಾವುದು ತಪ್ಪು ಎಂದು ಚೆನ್ನಾಗಿ ತಿಳಿದು\nಅದನ್ನು ಆಚರಣೆಗೆ ತರುವವರು. ತಾವು ಸತ್ಯವನ್ನು ಕಂಡು, ಸಮಾಜದ ಮುಂದೆ ಅದನ್ನು ನಡೆದು\nತೋರಿಸುವವರು. ಅಂಥವರ ಸೇವೆ. ಮಾಡು. ಜ್ಞಾನಿಗಳು ಸುಲಭವಾಗಿ ಸಿಗುವುದಿಲ್ಲ ಮತ್ತು ಅವರು\nಸಾಮಾನ್ಯವಾಗಿ ಪರೀಕ್ಷಿಸದೆ ಜ್ಞಾನ ಧಾರೆ ಮಾಡುವುದಿಲ್ಲ. ಏನೇ ಆದರೂ ಜ್ಞಾನಿಗಳ ಬೆನ್ನುಬಿಡಬೇಡ.\nನಿನ್ನಲ್ಲಿರುವ ಜ್ಞಾನ ತೃಷೆ ಗಾಢವಾಗಿದ್ದಲ್ಲಿ ಖಂಡಿತವಾಗಿ ಅವರು ಜ್ಞಾನ ಧಾರೆ ಮಾಡುತ್ತಾರೆ. ಜ್ಞಾನ ಬೇಕಿದ್ದರೆ\nಜ್ಞಾನಿಗಳು ತೆರೆದುಕೊಳ್ಳುವ ತನಕ ಕಾಯಬೇಕು. ಇದಕ್ಕೆ ಉತ್ತಮ ದೃಷ್ಟಾಂತ ಶ್ವೇತಕೇತು ಮತ್ತು\nಪ್ರಶ್ನೋಪನಿಷತ್ತಿನಲ್ಲಿ ಬರುವ ಪಿಪ್ಪಲಾದರ ಕಥೆ.\n\n(೭) ಶೌಚಮ್‌: ಶೌಚ ಎಂದರೆ ಶುಚಿತ್ವ. ಈ ವಿಷಯವನ್ನು ಹಿಂದಿನ ಅಧ್ಯಾಯದಲ್ಲಿ ಸ್ವಲ್ಪ ಮಟ್ಟಿಗೆ ನೋಡಿದ್ದೇವೆ.\nಕನ್ನಡದಲ್ಲಿ ಶೌಚಮ್‌ ಎಂದರೆ 'ಮಡಿ'. ನಾವು ಮಡಿ ಮಾಡುವುದನ್ನು ಬಿಟ್ಟು ಮಡಿಯಾಗುವುದನ್ನು ಕಲಿಯಬೇಕು.\n\nಸ್ನಾನ ಮಾಡಿ ಒದ್ದೆ ಬಟ್ಟೆ ಉಟ್ಟು ಯಾರನ್ನೂ ಮುಟ್ಟದೆ ಇದ್ದರೆ ಮಡಿಯಾಗಲು ಸಾಧ್ಯವಿಲ್ಲ. ಶುಚಿ ಎನ್ನುವುದು\nಮೂಲಭೂತವಾಗಿ ಮನಸ್ಸಿಗೆ ಸಂಬಂಧಪಟ್ಟದ್ದು. ಅದಕ್ಕೆ ಪೂರಕವಾಗಿ ದೇಹ ಶುದ್ಧಿ. ಪ್ರಾಪಂಚಿಕ ವಿಚಾರವನ್ನು\nಮರೆತು, ಮನಸ್ಸನ್ನು ಭಗವಂತನಲ್ಲಿ ನೆಲೆ ನಿಲ್ಲಿಸುವುದು ಮಡಿ. ನಾವು. ಕಾಯಾ-ವಾಚಾ-ಮನಸಾ\nಮಡಿಯಾಗಬೇಕು. ನಮ್ಮಲ್ಲಿ ಕೆಟ್ಟ ಯೋಚನೆ ಬಂದರೆ, ಕೆಟ್ಟ ಮಾತು ಬಾಯಲ್ಲಿ ಬಂದರೆ- ಆಗ ನಾವು ಮೈಲಿಗೆ.\nನಿಜವಾಗಿ ಕಾಯ-ವಾಚಾ-ಮನಸಾ ಮಡಿಯಾಗಿರುವವ ಮೈಲಿಗೆಯವರೊಂದಿಗಿದ್ದರೆ ಜೊತೆಗಿರುವವರೆಲ್ಲರೂ\nಮಡಿಯಾಗಬಹುದು. ಇದನ್ನೇ ಹಿಂದೆ “ಪಂಕ್ಷಿಪಾವನ' ಎಂದು ಕರೆಯುತ್ತಿದ್ದರು. ಪೂರ್ಣ ಮಡಿಯಾಗಿರುವವ\nಯಾವ ಪಂಕ್ತಿಯಲ್ಲಿ ಕುಳಿತನೋ ಆ ಪಂಕ್ತಿ ಮಡಿ. ಶಾಸ್ತ್ರ ಜ್ಞಾನವಿಲ್ಲದ ಮಡಿ ಮಡಿಯಲ್ಲ. ದೇವರ ಸ್ಮರಣೆ\nಮನಸ್ಸಿ ನಲ್ಲಿ, ದೇವರ ನಾಮ ಬಾಯಿಯಲ್ಲಿ ಇದ್ದಾಗ ನಾವು ಮಡಿ.\n\nಮನಸ್ಸನ್ನು ಶುದ್ಧ ಮಾಡುವುದಕ್ಕೋಸ್ಕರ ಆಚಮನ ಮತ್ತು ಪ್ರಾಣಾಯಾಮ. “ಓ ಭಗವಂತಾ, ನಿನ್ನ\nಕಾರುಣ್ಯಧಾರೆಯಿಂದ ನನ್ನ ಸಹಸ್ರಾರದಿಂದ ಅಮೃತವನ್ನು ಕೆಳಕ್ಕೆ ಇಳಿಸಿ, ನನ್ನ ಇಡೀ ಮೈ ಪಾವನವಾಗುವಂತೆ\nಮಾಡು, ನನ್ನೊಳಗಿನ ಎಲ್ಲಾ ಪಾಪಗಳೂ ಕೊಳೆಗಳೂ ಸುಟ್ಟು ತೊಳೆದುಹೋಗಲಿ” ಎನ್ನುವ\nಅನುಸಂಧಾನದಿಂದ, ಧ್ಯಾನಪೂರ್ವಕ ಪಾಪಪುರುಷ ನಿರಸನ ಮಾಡಬೇಕು. ಇಲ್ಲಿ ನಮ್ಮ ತಲೆಯಿಂದ\nಅಮೃತಧಾರೆ ಇಳಿದು ಬರುವುದನ್ನು ನಾವು ಅನುಭವಿಸಬೇಕು ಸ್ಥೈರ್ಯಮ್‌ : ಮನಸ್ಸಿನ ಸ್ಥಿರತೆ(Steadfastness) ಸ್ಥೈರ್ಯ. ನಮಗೆ ನಮ್ಮದೇ ಆದ ಸ್ವಂತ ನಿರ್ಧಾರ ಬೇಕು.\nಯಾರೋ ಹೇಳಿದಂತೆ ನಾವು ನಮ್ಮ ನಿರ್ಧಾರವನ್ನು ಬದಲಿಸಿಕೊಳ್ಳುತ್ತಾ ಗೊಂದಲಕ್ಕೊಳಗಾಗಬಾರದು. ನಾವು\nನಮ್ಮ ತಲೆಯಲ್ಲಿ ಚಿಂತಿಸಬಲ್ಲವರಾಗಬೇಕು. ನಮಗೆ ಯಾವುದಾದರೂ ಪ್ರಶ್ನೆ ಬಂದರೆ ಅದಕ್ಕೆ ಉತ್ತರವನ್ನು\nಕಂಡುಕೊಳ್ಳುವ ಸಾಮರ್ಥ್ಯ ನಮ್ಮ ತಲೆಯಲ್ಲೇ ಇರುತ್ತದೆ. “ಎಲ್ಲಿ ಪ್ರಶ್ನೆ ಇದೆಯೋ ಅಲ್ಲೇ ಉತ್ತರವೂ ಇರುತ್ತದೆ”.\nಶಾಸ್ತ್ರವನ್ನು ಚೆನ್ನಾಗಿ ಅಧ್ಯಾಯನ ಮಾಡಿ ನೀನೇ ನಿನ್ನ ಸಮಸ್ಯೆಗೆ ಉತ್ತರ ಕಂಡುಕೊಂಡು ದೃಢವಾಗಿ ಕೆಲಸ\nಮಾಡು. ಯಾರ ಯಾರೋ ಮಾತನ್ನು ಕೇಳಿ ಗೊಂದಲಗೊಳ್ಳದೆ ಸ್ಥೈರ್ಯವನ್ನು ಸಾಧಿಸು.\n\n(೯) ಆತ್ಮವಿನಿಗ್ರಹಃ : ಇಂದ್ರಿಯ ನಿಯಂತ್ರಣ (self control). ನಮ್ಮ ಇಂದ್ರಿಯ ನಮ್ಮ ಹಿಡಿತದಲ್ಲಿರಬೇಕು.\nಇಂದ್ರಿಯ ಹಿಡಿತಲ್ಲಿರಬೇಕಾದರೆ ನಾವು ನಮ್ಮ ಮನಸ್ಸನ್ನು ಹಿಡಿತದಲ್ಲಿಟ್ಟುಕೊಳ್ಳಬೇಕು. ಮನಸ್ಸಿನ ಕೈಯಲ್ಲಿ\nನೀನು ಮಂಗನಾಗಬೇಡ, ಮನಸ್ಸನ್ನು ನೀನು ನಿಯಂತ್ರಿಸು. ಇದಕ್ಕಾಗಿ ನಿನ್ನ ಮನಸ್ಸನ್ನು ದೇವರಲ್ಲಿ ನೆಲೆ\nನಿಲ್ಲಿಸು. ಹೀಗೆ ಮನೋನಿಗ್ರಹದಿಂದ ಇಂದ್ರಿಯ ನಿಗ್ರಹ ಸಾಧಿಸು.\n",
  "13.8": "ಇಂದ್ರಿಯ ಅರ್ಥೇಷು ವೈರಾಗ್ಯಮ್‌ ಅನಹಂಕಾರಃ ಏವ ಚ ।\n\nಜನ್ಮ ಮೃತ್ಯು ಜರಾ ವ್ಯಾಧಿ ದುಃಖ ದೋಷ ಅನುದರ್ಶನಮ್‌ -. ಇಂದ್ರಿಯ ವಿಷಯಗಳಲ್ಲಿ\nಮೈಮರೆಯದಿರುವುದು, ಸೊಕ್ಕು ಇರದಿರುವುದು, ಹುಟ್ಟು-ಸಾವು-ಮುಪ್ಪು-ಬೇನೆಗಳಿಂದ ದುಗುಡತುಂಬಿದ\nಬಾಳಿನ ದೋಷಗಳ ಎಚ್ಚರ,-\n\n(೧೦) ಇಂದ್ರಿಯಾರ್ಥೇಷು ವೈರಾಗ್ಯ : ಇಂದ್ರಿಯಗಳನ್ನು ಹೊರಪ್ರಪಂಚದತ್ತ ಹರಿಯದಂತೆ ತಡೆದು ಮನಸ್ಸನ್ನು\nಭಗವಂತನಲ್ಲಿ ನೆಲೆ ನಿಲ್ಲಿಸುವುದು. ಇದನ್ನು ಶಮ-ಧಮ ಎನ್ನುತ್ತಾರೆ. ಇಂದ್ರಿಯಗಳು ಲೌಕಿಕ ವಿಚಾರದತ್ತ\nಹರಿಯದಂತೆ ಮಾಡುವುದು ಧಮ ಮತ್ತು ಅದನ್ನು ಭಗವಂತನತ್ತ ಹರಿಯುವಂತೆ ಮಾಡುವುದು ಶಮ.\nಭಗವಂತನ ಬಗ್ಗೆ ತಿಳಿದಾಗ ಇಂದ್ರಿಯ ಇನ್ಯಾವುದರ ಕಡೆಗೂ ಹರಿಯುವುದಿಲ್ಲ. ಪ್ರಾಪಂಚಿಕವಾದ ಶಬ್ಧ, ಸ್ಪರ್ಶ,\nರೂಪ, ರಸ, ಗಂಧದ ಬಗ್ಗೆ ವಿರಕ್ತಿ ತಾಳು. ಉದಾಹರಣೆಗೆ ನಾಲಿಗೆ ಚಪಲ. ನಮ್ಮಲ್ಲಿ ಕೆಲವರು ಮನೆಯಲ್ಲಿ ಯಾವ\nರೀತಿ ಅಡಿಗೆ ಮಾಡಿದರೂ ಅಲ್ಲಿ ಅದು ಸರಿಯಾಗಿಲ್ಲ, ಇದು ಸರಿಯಾಗಿಲ್ಲ ಇತ್ಯಾದಿಯಾಗಿ ತಗಾದೆ ಎತ್ತುತ್ತಾರೆ.\nಈ ರೀತಿಯ ಚಪಲವನ್ನು ಬಿಟ್ಟುಬಿಡು. ಇಲ್ಲಿ ಬೇಕು ಬೇಡಗಳ ಆಯ್ಕೆ ಇಲ್ಲದೆ ಏನನ್ನು ಹಾಕಿದರೂ ಭಗವಂತನ\nಪ್ರಸಾದ ಎಂದು ಸ್ವೀಕರಿಸುವುದನ್ನು ಕಲಿ. ಈ ರೀತಿ ಶಮ-ಧಮ ಸಾಧಿಸು.\n\n(೧೧) ಅನಹಂಕಾರ: ಇದು ಎಲ್ಲಾ ಗುಣಗಳಿಗಿಂತ ಶ್ರೇಷ್ಠ ಗುಣ. ನಮ್ಮಲ್ಲಿ ಯಾವ ಗುಣವಿದ್ದರೂ ಅದು ನಮ್ಮ\nಅಹಂಕಾರದ ಮುಂದೆ ವ್ಯರ್ಥ. ಅಹಂಕಾರ(Attachment) ನಮ್ಮಲ್ಲಿನ ಎಲ್ಲಾ ಗುಣವನ್ನು ನಾಶ ಮಾಡುತ್ತದೆ.\nಅಹಂಕಾರವಿದ್ದೆಡೆ ಉಳಿದ ಗುಣಗಳಿಗೆ ಅಸ್ತಿತ್ವವೇ ಇಲ್ಲ. ಆದ್ದರಿಂದ ಕೃಷ್ಣ ಅದನ್ನು ಇಲ್ಲಿ “ಏವ-ಚ” ಎಂದು ಒತ್ತಿ\nಹೇಳಿದ್ದಾನೆ. 'ನಾನು ವಿದ್ವಾಂಸ, ನಾನು ಅನುಷ್ಠಾನವಂತ, ನಾನು ಮಡಿ' ಹೀಗೆ ನಮ್ಮನ್ನು ಅಹಂಕಾರ\nಪ್ರತಿಯೊಂದು ವಿಚಾರದಲ್ಲೂ ಕಾಡುತ್ತದೆ. ಹೀಗೆ ನಾವು ಅಹಂಕಾರಪಟ್ಟರೆ ನಮ್ಮ ಅನುಷ್ಠಾನ-ಅನುಷ್ಠಾನವೇ\nಆಗುವುದಿಲ್ಲ. ಎಲ್ಲಿ ಅಹಂಕಾರ ಕಾಡಿತೋ ಅಲ್ಲಿ ಸಾಧನೆ ವ್ಯರ್ಥವಾಗುತ್ತದೆ. ಎಲ್ಲಿ ಅಹಂಕಾರವಿರುತ್ತದೆ ಅಲ್ಲಿ\nದೇವರಿರುವುದಿಲ್ಲ-ಅಂದರೆ ಅಹಂಕಾರದಿಂದಾಗಿ ನಾವು ದೇವರಿಂದ ದೂರ ಸರಿಯುತ್ತೇವೆ. ಈ ಕಾರಣದಿಂದ\n“ನಾನು ಮಾಡಿದೆ, ನನ್ನಿಂದಾಯ್ತು' ಎಂದು ಬೀಗುವುದನ್ನು ಬಿಡು. ಭಗವಂತ ನನ್ನ ಕೈಯಿಂದ ಮಾಡಿಸಿದ ಎಂದು\nಆತನಿಗೆ ಕೃತಜ್ಞತೆಯನ್ನು ತೋರು.\n\n(೧೨) ಜನ್ಮ ಮೃತ್ಯು ಜರಾ ವ್ಯಾಧಿ ದುಃಖ ದೋಷ ಅನುದರ್ಶನಮ್‌: ಜೀವನವನ್ನು ಒಳನೋಟದಿಂದ ನೋಡು.\nಈ ಜೀವನ ಎನ್ನುವುದು ಹುಟ್ಟು ಸಾವು ಎನ್ನುವ ಎರಡು ದಡದ ನಡುವೆ ಹರಿಯುವ ಒಂದು ಪ್ರವಾಹ. ಈ\nಪ್ರವಾಹದಲ್ಲಿ ವ್ಯಾಧಿ, ಮುಪ್ಪು, ದುಃಖ, ಶೋಕ ಎನ್ನುವ ಅಲೆಗಳ ಸರಮಾಲೆ. ಈ ನಮ್ಮ ಬದುಕಿನ\nಉದ್ದೇಶವೇನು, ಭಗವಂತ ನಮ್ಮನ್ನು ಏಕೆ ಹುಟ್ಟಿಸಿದ, ಮಾನವ ಜನ್ಮವನ್ನು ಹೇಗೆ ಸಾರ್ಥಕ ಮಾಡಿಕೊಳ್ಳಬೇಕು\nಎನ್ನುವ ಅನುದರ್ಶನ ಮಾಡು. ಆಹಾರ ನಿದ್ರಾ ಭಯ ಮೈಥುನ ಇಷ್ಟೇ ಜೀವನವಲ್ಲ. ಇದನ್ನು ಪ್ರಾಣಿಗಳೂ\nಅನುಭವಿಸುತ್ತವೆ. ಆದ್ದರಿಂದ ಶಾಸ್ತ್ರವನ್ನು ಓದಿ ಸತ್ಯಕ್ಕೆ ಅನುಗುಣವಾದ ಯಥಾರ್ಥ ದರ್ಶನವನ್ನು ಮಾಡಿಕೋ.\nಕೇವಲ ಲೌಕಿಕ ಸುಖದ ನಿರೀಕ್ಷೆಯಲ್ಲಿ ಬದುಕುವುದನ್ನು ಬಿಟ್ಟು-ಸತ್ಯದ ಸಾಕ್ಷಾತ್ಕಾರಕ್ಕಾಗಿ, ಭಗವಂತನನ್ನು\nಸೇರುವುದಕ್ಕಾಗಿ ಬದುಕು. ಎಲ್ಲಾ ಲೌಕಿಕ ಸುಖ, ಸಂಪತ್ತು ನಿಸ್ಸಾ ರ. ಇದರಿಂದಾಚೆಗಿನ ಸಾರವಾದ\nಭಗವಂತನನ್ನು ತಿಳಿದು ಅದರತ್ತ ಹೆಜ್ಜೆಹಾಕು.",
  "13.9": "ಮಯಿ ಚಾನನ್ಯಯೋಗೇನ ಭಕ್ತಿರವ್",
  "13.10": "ಅಧ್ಯಾತ್ಮಜ್ಞಾನನಿತ್ಯತ್ವಂ ತತ್ತ್ವಜ್ಞಾನಾರ್ಥದರ್ಶನಮ್‌ |\nಏತಜ್‌ ಜ್ಞಾನಮಿತಿ ಪ್ರೋಕ್ತಮಜ್ಞಾನಂ ಯದತೋಃನ್ಯಥಾ",
  "13.11": "ಅಸಕ್ತಿಃ ಅನಭಿಷ್ಟಂಗಃ ಪುತ್ರ ದಾರ ಗೃಹ ಆದಿಷು |\n\nನಿತ್ಯಮ್‌ ಚ ಸಮಚಿತ್ತತ್ವಮ್‌ ಇಷ್ಟ ಅನಿಷ್ಟ ಉಪಪತ್ತಿಷು ॥\n\nಮಯಿಚ ಅನನ್ಯಯೋಗೇನ ಭಕ್ತಿಃ ಅವ್ಯಭಿಚಾರಿಣೀ |\n\nವಿವಿಕ್ತ ದೇಶ ಸೇವಿತ್ವಮ್‌ ಅರತಿಃ ಜನ ಸಂಸದಿ।\n\nಅಧ್ಯಾತ್ಮ ಜ್ಞಾನ ನಿತ್ಯತ್ವಮ್‌ ತತ್ತ್ವಜ್ಞಾನ ಅರ್ಥ ದರ್ಶನಮ್‌ |\n\nಏತತ್‌ ಜ್ಞಾನಮ್‌ ಇತಿ ಪ್ರೋಕ್ತಮ್‌ ಅಜ್ಞಾನಮ್‌ ಯತ್‌ ಅತಃ ಅನ್ಯಥಾ ಎ ಅಂಟಿಸಿಕೊಳ್ಳದಿರುವುದು, ಮಕ್ಕಳು\nಮಡದಿ ಮನೆ ಮುಂತಾದುವನ್ನು ಅತಿಯಾಗಿ ಹಚ್ಚಿಕೊಳ್ಳದಿರುವುದು, ಇಷ್ಟ-ಅನಿಷ್ಟಗಳು ಬಂದೊದಗಿದಾಗ\nಎಂದೆಂದೂ ಬಗೆಗೆಡಡಿರುವುದು, ಬೇರೆಡೆ. ಕದಲದೆ. ನನ್ನಲ್ಲೇ ಅಚಲವಾದ ಭಕ್ತಿ, ಏಕಾಂತವಾಸ,\nಜನಜಂಗುಳಿಯಲ್ಲಿ ಬೆರೆಯದಿರುವುದು, ಅಧ್ಯಾತ್ಮದ ಅರಿವಿನಲ್ಲೇ ನಿರಂತರ ಸ್ಥಿತಿ, ಅಪರೋಕ್ಷ ಜ್ಞಾನಕ್ಕಾಗಿ\nಶಾಸ್ತ್ರದ ಅಧ್ಯಯನ,|[ತತ್ವಜ್ಞಾನಕ್ಕೆ ಗೋಚರನಾದ ಭಗವಂತನ ಸಾಕ್ಷಾತ್ಕಾರ] ಇವೇ ಜ್ಞಾನ ಮತ್ತು ಜ್ಞಾನ\nಸಾಧನಗಳು. ಅದಕ್ಕಿಂತ ಬೇರೆಯಾದದ್ದು ಅಜ್ಞಾನ ಮತ್ತು ಅಜ್ಞಾನದ ದಾರಿ.\n\n(೧೩) ಅಸಕ್ತಿಃ : “ಸಕ್ತಿ' ಎಂದರೆ ಹಚ್ಚಿಕೊಳ್ಳುವುದು ಅಥವಾ ಅಂಟಿಸಿಕೊಳ್ಳುವುದು. ಈ\nವಿಚಾರವಾಗಿ ನಾವು ಹಿಂದೆ ಅನೇಕ ಬಾರಿ ಚರ್ಚಿಸಿದ್ದೇವೆ. ನಮ್ಮೆಲ್ಲಾ ದುಃಖಕ್ಕೂ ಮೂಲಕಾರಣ “ಸಕ್ತೆ'. ಆದ್ದರಿಂದ\nಯಾವುದನ್ನೂ ಅಂಟಿಸಿಕೊಳ್ಳಬೇಡ. ಹುಟ್ಟುವಾಗ ಸಾವು ಏನನ್ನೂ ತಂದಿಲ್ಲ, ಸಾಯುವಾಗ ಯಾವುದನ್ನೂ\nತೆಗೆದುಕೊಂಡು ಹೋಗುವುದಿಲ್ಲ. ಆದ್ದರಿಂದ ಲೌಕಿಕವಾದ ಈ ಸಕ್ತಿಯಿಂದ ದೂರ ನಿಲ್ಲು. ಬಂದದ್ದನ್ನು ಭಗವಂತನ\nಪ್ರಸಾದವೆಂದು ಸ್ವೀಕರಿಸು, ಹೋದಾಗ ಭಗವಂತನ ಇಚ್ಛೆ ಎಂದು ಸಂತೋಷದಿಂದಿರು.\n\n(೧೪) ಅನಭಿಷ್ಟಂಗಃ ಪುತ್ರ ದಾರ ಗೃಹ ಆದಿಷು : ಅಭಿಷ್ಟಂಗ ಎಂದರೆ ಅತಿಯಾಗಿ ಹಚ್ಚಿಕೊಳ್ಳುವುದು(Over-attachment). ಮನೆ, ಹೆಂಡತಿ(ಗಂಡ/ಹೆಂಡತಿ) ಮಕ್ಕಳು ಇತ್ಯಾದಿಯನ್ನು ಅತಿಯಾಗಿ ಹಚ್ಚಿಕೊಳ್ಳಬೇಡ\nಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಇಲ್ಲಿ ಮನೆ ಸಂಸಾರವನ್ನು ಹಚ್ಚಿಕೊಳ್ಳದೇ ಇರುವುದು ಎಂದರೆ ಎಲ್ಲವನ್ನೂ ತೊರೆದು ಕಾಡಿಗೆ\nಹೋಗುವುದಲ್ಲ. \"ಇದನ್ನು ಬಿಟ್ಟು ನಾನು ಇರಲಾರೆ' ಎನ್ನು ವ ಅಭಿಷ್ಟಂಗ ಬಿಟ್ಟುಬಿಡುವುದು ಅಷ್ಟೆ. ಜೀವನದಲ್ಲಿ\nಏನು ಬರುತ್ತದೋ ಅದನ್ನು ಸಾಕ್ಷೀಭೂತನಾಗಿ ನೋಡು. ಜೀವನವೇ ಒಂದು ನಾಟಕ, ಅದರಲ್ಲಿ ನೀನೇ\n\nಪಾತ್ರಧಾರಿ , ನೀನೇ ಪ್ರೇಕ್ಷಕ. ಭಗವಂತ ನಿರ್ದೇಶಕ. ಇಲ್ಲಿ ನನ್ನ ಮಕ್ಕಳೇ ನನ್ನ ಬದುಕು, ನನ್ನ ಪತಿ/ಪತ್ನಿ ನನ್ನ\nಬದುಕು, ನನ್ನ ಸಂಪಾದನೆಯೇ ನನ್ನ ಬದುಕು, ಇದನ್ನು ಬಿಟ್ಟು ನನ್ನ ಅಸ್ತಿತ್ವವಿಲ್ಲ ಎನ್ನುವ ಅತಿಯಾದ ಅಭಿಷ್ಟಂಗ\nಬೇಡ. ಪ್ರೀತಿಸು-ಆದರೆ ಹಚ್ಚಿಕೊಂಡು ಕೊರಗಬೇಡ, ನಿರಾಶನಾಗಬೇಡ. ಈ ರೀತಿ ಬದುಕಲು ಕಲಿತಾಗ ಜೀವನ\nಸುಂದರವಾಗಿರುತ್ತದೆ. ನಮ್ಮಿಂದ ನಮ್ಮ ಮಕ್ಕಳು ದೂರವಾದರೆ, ಹೆಂಡತಿ/ಗಂಡ ದೂರವಾದರೆ, ನಾವು ನಮ್ಮ\nಸಂಪತ್ತನ್ನು(ಮನೆ, ಆಸ್ತಿ ಇತ್ಯಾದಿ) ಕಳೆದುಕೊಂಡರೆ ದುಃಖ-ನಿರಾಶೆಯಾಗುವುದಿಲ್ಲ. ಈ ರೀತಿ ಬದುಕಿದಾಗ\nಜೀವನದಲ್ಲಿ ಏನು ದುರಂತ ಬಂದರೂ ಅದು ನಮ್ಮ ಪಾಲಿನ ಪಾತ್ರಾಭಿನಯ ಎನ್ನುವ ಭಾವನೆಯಿಂದ ನಾವು\nಅದನ್ನು ಸ್ವೀಕರಿಸಲು ಸಾಧ್ಯವಾಗುತ್ತದೆ-ಆಘಾತವಾಗುವುದಿಲ್ಲ.\n\n(೧೫) ನಿತ್ಯಮ್‌ ಚ ಸಮಚಿತ್ತತ್ವಮ್‌ ಇಷ್ಟ ಅನಿಷ್ಟ ಉಪಪತ್ತಿಷು : ಜೀವನದಲ್ಲಿ ಇಷ್ಟವಾದ ಘಟನೆ\nನಡೆಯಬಹುದು, ಅನಿಷ್ಟವಾದ ಘಟನೆ ನಡೆಯಬಹುದು. ಇಷ್ಟ ಅನಿಷ್ಟಗಳು ಬಂದೊದಗಿದಾಗ ಮನಸ್ಸಿನ\nಸಮತೋಲನವನ್ನು ಕಳೆದುಕೊಳ್ಳದೆ ಎಲ್ಲಾ ಸಮಯದಲ್ಲೂ ಸಮಚಿತ್ತತ್ವದಿಂದಿರಲು ಕಲಿ. ನಾವು ಅನಿಷ್ಟ\nಅಂದುಕೊಂಡಿದ್ದು ಅನಿಷ್ಟ ವಾಗಿರಬೇಕೆಂದಿಲ್ಲ ಅಥವಾ ನಾವು ಇಷ್ಟ ಪಟ್ಟ ದ್ದು ಒಳ್ಳೆಯದಾಗಿರಬೇಕೆಂದಿಲ್ಲ.\nಆದ್ದರಿಂದ ಇಷ್ಟ-ಅನಿಷ್ಟ ಎಂದು ಲೇಪ ಹಚ್ಚದೆ ಬಂದಿದ್ದನ್ನು “ನಾಹಂ ಕರ್ತಾ ಹರಿಃ ಕರ್ತಾ' ಎಂದು ಸ್ವೀಕರಿಸಲು\nಕಲಿ. ನಮ್ಮ ಜೀವನದಲ್ಲಿ ನಡೆಯುವ ಪ್ರತಿಯೊಂದು ಘಟನೆ ಭಗವಂತ ನಮ್ಮ ತರಬೇತಿಗಾಗಿ ಸೃಷ್ಟಿಸಿರುವ\nಪ್ರಾಯೋಗಿಕ(Practical)ಶಿಕ್ಷಣ. ಭಗವಂತ ನಮಗೆ ದುಃಖವನ್ನು ಕೊಟ್ಟು ನಮ್ಮನ್ನು ಜಾಣರನ್ನಾಗಿ ಮಾಡುತ್ತಾನೆ\nಎನ್ನುವ ಸತ್ಯವನ್ನು ಅರಿತು ಬದುಕು.\n\n(೧೬) ಮಯಿ ಚ ಅನನ್ಯಯೋಗೇನ ಭಕ್ತಿಃ ಅವ್ಯಭಿಚಾರಿಣೀ: ಭಗವಂತನಲ್ಲಿ ನಿರಂತರ ಪರಿಶುದ್ಧ ಭಕ್ತಿ ಇರಲಿ.\nಭಗವಂತ ಒಬ್ಬನೆ, ಆತನ ನಾಮ ಹಲವು. ಆತನಲ್ಲಿ ಅನನ್ಯವಾದ ಭಕ್ತಿಯನ್ನಿಡು. ಇಲ್ಲಿ ಏಕಭಕ್ತಿ ಬಹಳ ಮುಖ್ಯ.\nಒಂದೊಂದು ದಿನ ಒಂದೊಂದು ದೇವರನ್ನು ಪೂಜಿಸುವುದು, ಒಂದು ದೇವತೆಯನ್ನು ಪೂಜಿಸಿದಾಗ ಇನ್ನೊಂದು\nದೇವತೆ ಕೋಪಗೊಳ್ಳಬಹುದು ಎನ್ನುವ ಭಯದಿಂದ ಅನೇಕ ದೇವತಾ ಆರಾಧನೆ ಮಾಡುವುದನ್ನು ಮಾಡಿದರೆ\nಅದು ವ್ಯಭಿಚಾರವಾಗುತ್ತದೆ. ಆದ್ದರಿಂದ ಕೃಷ್ಣ ಇಲ್ಲಿ “ನಿನ್ನ ಭಕ್ತಿ ಅನನ್ಯವಾಗಿದ್ದು ಅವ್ಯಭಿಚಾರಿಣಿಯಾಗಿರಬೇಕು”\nಎಂದು ಒತ್ತಿ ಹೇಳಿದ್ದಾನೆ. ಭಗವಂತ ಸರ್ವಸಮರ್ಥ, ಸರ್ವಶಕ್ತ, ಜಗತ್ಫನ್ಮಾದಿ ಕಾರಣ ಎನ್ನುವ ನಿಷ್ಠೆ ನಿನ್ನಲ್ಲಿರಲಿ.\nದೇವರ ಮೇಲೆ ನಂಬಿಕೆ ಇಲ್ಲದೆ ಯಾವ ಶಾಸ್ತ್ರ ಓದಿ ಏನೂ ಉಪಯೋಗವಿಲ್ಲ. ಭಗವಂತನ ಮೇಲಿನ ಪೂರ್ಣ\nನಂಬಿಕೆಯಿಂದ ಮಾತ್ರ ಜ್ಞಾನ ಸಾಧನೆ ಸಾಧ್ಯ\n\n(೧೭) ವಿವಿಕ್ತ ದೇಶ ಸೇವಿತ್ವಮ್‌: ಸಾಧ್ಯವಾದಷ್ಟು ಅತಿ ಹೆಚ್ಚು ಸಾತ್ವಿಕ ಕಂಪನವಿರುವ ಕಡೆ, ಸಾತ್ವಿಕ ಜನರ\nಜೊತೆಗೆ ವಾಸ ಮಾಡಲು ಪ್ರಯತ್ನಿಸು. ಪೂರ್ಣಪ್ರಮಾಣದಲ್ಲಿ ಅಖಂಡವಾದ ಸಾತ್ವಿಕ ಕಂಪನವಿರುವ ಸ್ಥಳ\nಪುಣ್ಯಕ್ಷೇತ್ರವೆನಿಸುತ್ತದೆ. ಅಂತಹ ಸ್ಥಳದಲ್ಲಿ ಒಳ್ಳೆಯದನ್ನು ಮಾತನಾಡುವ, ಒಳ್ಳೆಯ ಚಿಂತನೆ ಮಾಡುವ\nಸಜ್ಜನರೊಂದಿಗೆ ವಾಸಮಾಡು. ಇದು ಸಾಧ್ಯವಾಗದೇ ಇದ್ದಲ್ಲಿ ಆದಷ್ಟು ಏಕಾಂತವಾಸವನ್ನು ಅಭ್ಯಾಸ ಮಾಡು.\nನಾಲ್ಕು ಜನರೊಂದಿಗೆ ಸೇರಿ ಹಾಳು ಹರಟೆಯಲ್ಲಿ ನಿನ್ನ ಅಮೂಲ್ಯವಾದ ಜನ್ಮವನ್ನು ವ್ಯರ್ಥ ಮಾಡಿಕೊಳ್ಳಬೇಡ.\n(೧೮) ಅರತಿಃ ಜನ ಸಂಸದಿ: ಎಲ್ಲಿ ಬೇಡವಾದ ವಿಚಾರಕ್ಕಾಗಿ ಜನಜಂಗುಳಿ ಸೇರುತ್ತದೋ, ಅಂತಹ\nಜನಜಂಗುಳಿಯಿಂದ ದೂರವಿರು.\n\n(೧೯) ಅಧ್ಯಾತ್ಮ ಜ್ಞಾನ ನಿತ್ಯತ್ವಮ್‌ ; ಅಧ್ಯಾತ್ಮದ ಅರಿವಿನಲ್ಲಿ ನಿರಂತರವಾಗಿರು. ಮೊದಲು ಪಿಂಡಾಂಡ-\nಬ್ರಹ್ಮಾಂಡವನ್ನು ತಿಳಿ, ಆನಂತರ ಇದನ್ನು ತಿಳಿಯುವ ಅಪೂರ್ವ ಮನಸ್ಸಿನ ವಿಸ್ಮಯದ ಬಗ್ಗೆ ತಿಳಿ, ನಂತರ\n'ನಾನು' ಎಂದರೆ ಏನು(awareness of self) ಎನ್ನುವುದನ್ನು ತಿಳಿ. ಇದು ತಿಳಿದಮೇಲೆ ಈ ಆತ್ಮವನ್ನು\nನಿಯಂತ್ರಿಸುವ ಪರಮಾತ್ಮನನ್ನು ತಿಳಿ. ಇದು ಅಧ್ಯಾತ್ಮಜ್ಞಾನ. ನಿನ್ನ ಅಧ್ಯಯನದ ಗುರಿ ಅಧ್ಯಾತ\nಜ್ಞಾನವಾಗಿರಲಿ.\n\n(೨೦) ತತ್ತ್ವಜ್ಞಾನ ಅರ್ಥ ದರ್ಶನಮ್‌: ಜಗತ್ತಿನ ಮೂಲಭೂತ ಸತ್ಯ ತಿಳಿಯುವುದಕ್ಕೆ ನಿನ್ನ ಅಧ್ಯಯನ\nಮೀಸಲಿರಲಿ. ಮೇಲಿನ ಎಲ್ಲಾ ಗುಣಗಳಿಂದ ಎಲ್ಲಾ ಶಾಸ್ತ್ರಗಳಿಗೆ ವಿಷಯಭೂತನಾದ, ಎಲ್ಲಾ ಶಾಸ್ತ್ರಗಳಿಂದ\nಪ್ರತಿಪಾಧ್ಯನಾದ ಭಗವಂತನ ಸಾಕ್ಷಾತ್ಕಾರ ಪಡೆ.\n\nಇಲ್ಲಿ ಹೇಳಿರುವ ಗುಣಗಳೇ ಜ್ಞಾನ ಮತ್ತು ಜ್ಞಾನ ಸಾಧನಗಳು. ಇದಕ್ಕಿಂತ ಬೇರೆಯಾಗಿರುವುದು ಅಜ್ಞಾನ ಮತ್ತು\nಅಜ್ಞಾನದ ಗುರಿ.\n\n6\n\nಜ್ಞಾನ ಸಾಧನಗಳನ್ನು ವಿವರಿಸಿದ ಕೃಷ್ಣ ಮುಂದಿನ ಆರು ಶ್ಲೋಕಗಳಲ್ಲಿ ಶಬ್ದದ ಮಿತಿಯಿಂದ ಆಚೆಗಿರುವ\nಭಗವಂತನ ವರ್ಣನೆಯನ್ನು ನಮ್ಮ ಮುಂದಿಡುತ್ತಾನೆ. ದೇವರು ಹೇಗಿದ್ದಾನೆ, ಆತನ ರೂಪವನ್ನು ಹೇಗೆ\nಅನುಸಂಧಾನ ಮಾಡಬೇಕು ಎನ್ನುವ ವಿಚಾರವನ್ನು ಕೃಷ್ಣ ಇಲ್ಲಿ ಸುಂದರವಾಗಿ ವರ್ಣಿಸಿದ್ದಾನೆ. ಈ ಶ್ಲೋಕಗಳಲ್ಲಿ\nಒಂದೊಕ್ಕೊಂದು ವ್ಯತಿರಿಕ್ತ(Contradicting)ವಾಗಿ ಕಾಣುವ ಅನೇಕ ವಿಷಯಗಳನ್ನು ನಾವು ಕಾಣಬಹುದು.\nಉದಾಹರಣೆಗೆ: ಭಗವಂತ ನಿರ್ಗುಣ ಆದರೆ ಆತ ಸರ್ವಗುಣಪೂರ್ಣ; ಭಗವಂತ ಅಚಲ ಆದರೆ ಆತ\nಚಲಿಸುತ್ತಾನೆ; ಭಗವಂತ ನಿರಾಕಾರ ಆದರೆ ಆತ ಸಾಕಾರ; ಭಗವಂತನನ್ನು ತಿಳಿಯಲು ಅಸಾಧ್ಯ ಆದರೆ\nಆತನನ್ನು ತಿಳಿಯಬಹುದು; ಭಗವಂತನಿಗೆ ಇಂದ್ರಿಯಗಳಿಲ್ಲ ಆದರೆ ಆತನಿಗೆ ಇಂದ್ರಿಯಗಳಿವೆ; ಆತ\nದೂರದಲ್ಲಿದ್ದಾನೆ ಆದರೆ ಹತ್ತಿರದಲ್ಲಿದ್ದಾನೆ; ಇತ್ಯಾದಿ. ಈ ರೀತಿಯ ವರ್ಣನೆಯನ್ನು ಭಗವಂತನಿಗಲ್ಲದೆ\nಇನ್ಯಾರಿಗೂ ಕೊಡಲು ಬರುವುದಿಲ್ಲ. ಇವೆಲ್ಲವುದರ ವಿವರಣೆಯನ್ನು ಮುಂದಿನ ಶ್ಲೋಕಗಳಲ್ಲಿ ಕಾಣಬಹುದು.\n",
  "13.12": "ಜ್ಞೇಯಮ್‌ ಯತ್‌ ತತ್‌ ಪ್ರವಕ್ಷ್ಯಾಮಿ ಯತ್‌ ಜ್ಞಾತ್ವಾ ಅಮೃತಮ್‌ ಅಶ್ನುತೇ ।\n\nಅನಾದಿ ಮತ್ಚರಮ್‌ ಬ್ರಹ್ಮ ನ ಸತ್‌ ತತ್‌ ನ ಅಸತ್‌ ಉಚ್ಯತೇ - ಯಾವುದನ್ನು ತಿಳಿದು ಸಾವನ್ನು ಗೆಲ್ಲುವನೋ\nಅಂತಹ “ಜ್ಞೇಯ'ವನ್ನು ಹೇಳುತ್ತೇನೆ: ಹುಟ್ಟಿರದ,[ದೇಹದಿಂದಲೂ ಹುಟ್ಟದ] ಪರಬ್ರಹ್ಮವೇ ಜ್ಞೇಯ. ಅದು ಕಣ್ಣಿಗೆ\nಕಾಣುವ ಮಣ್ಣು-ನೀರು-ಬೆಂಕಿಗಿಂತಲೂ ಬೇರೆ; ಕಾಣದ ಗಾಳಿ -ಆಗಸಗಳಿಗಿಂತಲೂ ಬೇರೆ ಎನ್ನಿ ಸಿದೆ.\n\nಇಲ್ಲಿ ಕೃಷ್ಣ ಜ್ಞಾನ ಸಾಧನಗಳ ಮೂಲಕ ತಿಳಿದುಕೊಳ್ಳಬೇಕಾದ ಜ್ಞೇಯನ ಬಗ್ಗೆ ವಿವರಿಸುತ್ತಾ ಹೇಳುತ್ತಾನೆ:\n“ಯಾವುದನ್ನು ಪ್ರತ್ಯಕ್ಷವಾಗಿ ಶಬ್ದಗಳು ಹೇಳಲಾರವೋ, ಯಾವ ಜ್ಞಾನವನ್ನು ತಿಳಿದುಕೊಂಡು ನೀನು\n\nಅಮೃತತ್ವವನ್ನು ಸವಿಯುವೆಯೋ-ಅದನ್ನು ನಾನು ನಿನಗೆ ಹೇಳುತ್ತೇನೆ” ಎಂದು. ಭಗವಂತ ಅನಾದಿಮತ್‌.\nಆತನಿಗೆ ನಶ್ಚರವಾದ ಪಂಚಭೂತಗಳಿಂದಾದ ಯಾವ ಆಕಾರವೂ ಇಲ್ಲ. ಆತ ಜ್ಞಾನಾನಂದ ಸ್ವರೂಪ.\nಭಗವಂತನ ಗುಣಕ್ರಿಯೆ ಎಲ್ಲವೂ ಅನಾದಿಮತ್‌. ಸದ್ಗುಣಗಳಿಂದ ತುಂಬಿರುವ ಭಗವಂತ ನಮಗೆ\nಪೂರ್ಣತೆಯನ್ನು ಕೊಡುವವ. ಆತ ಸರ್ವರಕ್ಷಕ, ಆತನಿಂದ ಹಿರಿದಾದ ತತ್ವ ಇನ್ನೊಂದಿಲ್ಲ. ಇಂತಹ\nಭಗವಂತನನ್ನು ನಾವು ಪೂರ್ಣವಾಗಿ ಅರಿಯಲು ಸಾಧ್ಯವಿಲ್ಲ. ಅದು ನಮ್ಮ ಅರಿವಿಗೆ ಎಟುಕದ್ದು. ಹೀಗಿದ್ದರೂ\nಕೂಡಾ ಆತನನ್ನು ನಮ್ಮ ಸಾಮರ್ಥ್ಯಕ್ಕನುಗುಣವಾಗಿ ನಾವು ಯಥಾರ್ಥ ತಿಳಿಯಲು ಸಾಧ್ಯ.\n",
  "13.13": "ಸರ್ವತಃಪಾಣಿಪಾದಮ್‌ ತತ್‌ ಸರ್ವತಃ ಅಕ್ಷಿ ಶಿರಃ ಮುಖಮ್‌ ।\nಸರ್ವತಃ ಶ್ರುತಿಮತ್‌ ಲೋಕೇ ಸರ್ವಮ್‌ ಆವೃತ್ಯ ತಿಷ್ಠತಿ-ಎಲ್ಲೆಡೆಯೂ ಅದಕ್ಕೆ ಕೈಕಾಲುಗಳು; ಎಲ್ಲೆಡೆಯೂ\nಕಣ್ಣು-ತಲೆ-ಬಾಯಿಗಳು; ಎಲ್ಲೆಡೆಯೂ ಅದಕ್ಕೆ ಕಿವಿ; ಅದು ಲೋಕದೊಳಗೆಲ್ಲವನ್ನು ಆವರಿಸಿ ನಿಂತಿದೆ.\n\nಭಗವಂತ ಎಲ್ಲೆಡೆ ತುಂಬಿದ್ದಾನೆ. ಆತನಿಗೆ ಎಲ್ಲಾಕಡೆ ಕೈ ಕಾಲುಗಳು; ಎಲ್ಲಾ ಕಡೆ ಕಿವಿ, ಮುಖ, ಬಾಯಿ,\nಕಣ್ಣು.(ಸಂಸ್ಕೃತದಲ್ಲಿ ಮುಖ ಎಂದರೆ ಮುಖವೂ ಹೌದು-ಬಾಯಿಯೂ ಹೌದು. ಸಮೃದ್ಧವಾದ ಈ ಭಾಷೆಯಲ್ಲಿ\n'ಬಾಯಿ'ಯನ್ನು ಸೂಚಿಸುವ ಪ್ರತ್ಯೇಕ ಪದ ಇಲ್ಲಃ). ಈ ಕಾರಣದಿಂದ ಭಗವಂತನಿಗೆ ತಿಳಿಯದಂತೆ ನಾವು\nಯಾವ ಕಾರ್ಯವನ್ನೂ ಮಾಡಲು ಸಾಧ್ಯವಿಲ್ಲ. ಆತ ಸರ್ವಜ್ಞ, ಸರ್ವಗತ, ಸರ್ವಸಮರ್ಥ. ಇದೆಲ್ಲವನ್ನು ಶ್ರುತಿ\nಪ್ರಮಾಣೀಕರಿಸುತ್ತದೆ. ಆದಿಯಲ್ಲಿ ವೇದವನ್ನು ಉಚ್ಛಾರ ಮಾಡಿದವನು ಭಗವಂತ. ಆತ ಎಲ್ಲವುದರ ಒಳಗೂ\nಹೊರಗೂ ಆವರಿಸಿ ನಿಂತಿದ್ದಾನೆ. ಅಖಂಡವಾದ ಭಗವಂತನೊಳಗೆ ಆತನ ಅನಂತ ರೂಪಗಳಿವೆ. ಪ್ರತಿಯೊಂದು\nರೂಪಕ್ಕೂ ಜ್ಞಾನಾನಂದಮಯವಾದ, ಸ್ವರೂಪಭೂತವಾದ ಇಂದ್ರಿಯಗಳಿವೆ. ನಮ್ಮ ಸರ್ವ ಇಂದ್ರಿಯದಲ್ಲೂ\nಆತ ತುಂಬಿ ನಿಂತು ನಡೆಸುತ್ತಿದ್ದಾನೆ.\n",
  "13.14": "ಸರ್ವೇಂದ್ರಿಯ ಗುಣ ಆಭಾಸಂ ಸರ್ವೇಂದ್ರಿಯ ವಿವರ್ಜಿತಮ್‌ |\n\nಅಸಕ್ತಮ್‌ ಸರ್ವಭೃತ್‌ ಚ ಏವ ನಿರ್ಗುಣಮ್‌ ಗುಣಭೋಕ್ರ ಚ -ಎಲ್ಲಾ ಇಂದ್ರಿಯಗಳನ್ನು, ಎಲ್ಲಾ ವಿಷಯಗಳನ್ನು\nಬೆಳಗಿಸುತ್ತಿರುವುದು; ಅದಕ್ಕೆ ಭೌತಿಕವಾದ ಯಾವ ಇಂದ್ರಿಯಗಳೂ ಇಲ್ಲ. ಯಾವುದಕ್ಕೂ ಅಂಟದೆ ಎಲ್ಲವನ್ನು\nಹೊತ್ತಿದೆ. ತ್ರಿಗುಣಗಳ ನಂಟಿಲ್ಲ; ಎಲ್ಲಾ ಸದ್ಗುಣಗಳ ನೆಲೆ.\n\nಜಗತ್ತಿನಲ್ಲಿರುವ ಎಲ್ಲಾ ಜೀವಜಾತಗಳು ತಮ್ಮ ಇಂದ್ರಿಯಗಳಿಂದ ಇಂದ್ರಿಯ ವಿಷಯವನ್ನು ಗ್ರಹಿಸುವುದು\nಭಗವಂತನಿಂದ. ಇಂತಹ ಭಗವಂತನಿಗೆ ಪಾಂಚಭೌತಿಕವಾದ, ನಶ್ಚರವಾದ, ನಮ್ಮಂತೆ ಒಂದು ದಿನ\n\nನಾಶವಾಗುವ, ತನ್ನ ಸ್ವರೂಪಕ್ಕಿಂತ ಭಿನ್ನವಾದ ಯಾವ ಇಂದ್ರಿಯಗಳೂ ಇಲ್ಲ. ಈ ಜಗತ್ತನ್ನು ಹೊತ್ತಿರುವ ತಂದೆ\nಆ ಭಗವಂತ ಗಂಡು. ಜಗತ್ತನ್ನು ಹೆತ್ತ ಆತ ತಾಯಿಯೂ ಹೌದು. ಭೌತಿಕವಾಗಿ ಆತ ಗಂಡೂ ಅಲ್ಲ, ಹೆಣ್ಣೂ ಅಲ್ಲ.\nಆತ ಸ್ವರೂಪಭೂತವಾಗಿ ಗಂಡೂ ಹೌದು-ಹೆಣ್ಣೂ ಹೌದು. ಭಗವಂತ ಎಲ್ಲರೊಳಗೆ ತುಂಬಿದ್ದಾನೆ ಆದರೆ ಆತ\nಯಾವುದನ್ನೂ ಅಂಟಿಸಿಕೊಂಡಿಲ್ಲ. ಆತ ಎಲ್ಲವನ್ನೂ ಹೊತ್ತಿದ್ದಾನೆ ಆದರೆ... ಅದರ ಬಾಂಧವ್ಯದ\nಬೆಸುಗೆ(bond) ಆತನಿಗಿಲ್ಲ. ಭಗವಂತ ತ್ರಿಗುಣಾತೀತ. ಆತನಿಗೆ ತ್ರಿಗುಣಗಳ ನಂಟಿಲ್ಲ. ಆದರೆ ಆತ\nಸದ್ಗುಣಗಳ ನೆಲೆ. ಅವನು ನಿರಾಕಾರನೂ ಹೌದು, ಸಾಕಾರನೂ ಹೌದು.\n\nಬಹಿರಂತಶ್ಚ ಭೂತಾನಾಮಚರಂ ಚರಮೇವ ಚ |\nಸೂಕ್ಷ್ಮತ್ವಾತ್‌ ತದವಿಜ್ಛೇಯಂ ದೂರಸ್ಥಂ ಚಾಂತಿಕೇ ಚ ತತ್‌.",
  "13.15": "ಬಹಿಃ ಅಂತಃ ಚ ಭೂತಾನಾಮ್‌ ಆಚರಮ್‌ ಚರಮ್‌ ಏವ ಚ ।\n\nಸೂಕ್ಷ್ಮತ್ವಾತ್‌ ತತ್‌ ಅವಿಜ್ಞೇಯಮ್‌ ದೂರಸ್ಥಮ್‌ ಚ ಅಂತಿಕೇ ಚ ತತ್‌ -ಅದು ಜೀವಿಗಳ ಹೊರಗಿದೆ; ಒಳಗೂ\nಇದೆ; ಆದರೂ ಎಲ್ಲೆಡೆ ಚಲಿಸುತ್ತಿದೆ. ಅದು ಅಣುವಿಗಿಂತ ಅಣು; ಅದಕ್ಕೆಂದೇ ತಿಳಿವಿಗೆಟುಕದ್ದು. ಅದು\nದೂರದಲ್ಲಿದ್ದರೂ ಎಲ್ಲರ ಹತ್ತಿರದಲ್ಲಿದೆ.\n\nಭೂತ ಎಂದರೆ ಸಮಸ್ತ ಬ್ರಹ್ಮಾಂಡ, ಸಮಸ್ತ ಜೀವಜಾತ(ಪಿಂಡಾಂಡ). ಭಗವಂತ ಈ ಬ್ರಹ್ಮಾಂಡದ ಒಳಗೂ\nಹೊರಗೂ ತುಂಬಿದ್ದಾನೆ. ನಾರಾಯಣ ಉಪನಿಷತ್ತಿನಲ್ಲಿ ಹೇಳುವಂತೆ “ಅಂತರ್ಬಹಿಶ್ಚ ತತ್‌-ಸರ್ವಂ ವ್ಯಾಪ್ಯ\nನಾರಾಯಣಃ ಸ್ಥಿತಃ”. ನಮ್ಮ ಒಳಗೆ ಮತ್ತು ಹೊರಗೆ ತುಂಬಿ, ಎಲ್ಲವನ್ನೂ ವ್ಯಾಪಿಸಿ ನಿಂತಿರುವ ಭಗವಂತ-\nನಾರಾಯಣ. ಒಂದು ಅತಿಕ್ಷುದ್ರ ಜೀವದಿಂದ ಹಿಡಿದು ಚತುರ್ಮುಖ ಬ್ರಹ್ಮನ ತನಕ ಎಲ್ಲರ ಒಳಗೂ ಹೊರಗೂ\nಭಗವಂತ ತುಂಬಿದ್ದಾನೆ. ನಮ್ಮ ಒಳಗೆ ಅಂತರ್ಯಾಮಿಯಾಗಿ ಬಿಂಬರೂಪದಲ್ಲಿದ್ದು ನಮ್ಮನ್ನು ನಡೆಸುತ್ತಿದ್ದಾನೆ\nಮತ್ತು ನಮ್ಮ ಹೊರಗೆ ನಿಂತು ನಮ್ಮನ್ನು ಧಾರಣೆ ಮಾಡಿದ್ದಾನೆ. ಜ್ಞಾನಿಗಳಿಗೆ ಅವರ ಅಂತರಂಗದಲ್ಲಿ ದರ್ಶನ\nಕೊಡುವ ಭಗವಂತ ಅಜ್ಞಾನಿಗಳಿಗೆ ಬಹಿ(ಬಹುದೂರ). ಸರ್ವಗತನಾದ ಭಗವಂತ ಅಚಲ ಆದರೆ ಆತನ ಅನಂತ\nರೂಪಗಳು ಸದಾ ಚಲಿಸುತ್ತಿರುತ್ತವೆ. ಸಮಸ್ತ ಚರಾಚಾರಾತ್ಮಕ ಜೀವದೊಳಗೆ ಭಗವಂತ ತುಂಬಿ ನಿಂತಿದ್ದಾನೆ.\nಭಗವಂತ ಅಣುವಿನೊಳಗೆ ಅಣುವಾಗಿ ತುಂಬಿದ್ದಾನೆ. ಭಗವಂತ ಜ್ಞೇಯ ಆದರೆ ವಿಜ್ಞೇಯ ಅಲ್ಲ. ಭಗವಂತನ\nವಿವರವನ್ನು ನಾವು ಕಿಂಚಿತ್‌ ತಿಳಿಯಬಹುದು ಆದರೆ ಪೂರ್ಣವಾಗಿ ಅರಿಯಲು ಸಾಧ್ಯವಿಲ್ಲ. ನಾವು\nಸಮುದ್ರದಲ್ಲಿರುವ ಒಂದು ಪುಟ್ಟ ಮೀನಿನಂತೆ. ಅದು ಹೇಗೆ ಸಮುದ್ರದ ಅಗಾಧತೆಯನ್ನು ತಿಳಿಯಲಾರದೋ\nಹಾಗೆ ಜಗತ್ತಿನ ಯಾವ ಜೀವಜಾತವೂ ಭಗವಂತನನ್ನು ಪೂರ್ಣವಾಗಿ ತಿಳಿಯಲಾರವು. ಏಕೆಂದರೆ ಅದು ನಮ್ಮ\nಮನಸ್ಸು ಗ್ರಹಿಸಲಾರದಷ್ಟು ಸೂಕ್ಷ್ಮ ಮತ್ತು ಅಗಾಧ.\n",
  "13.16": "ಅವಿಭಕ್ತಮ್‌ ಚ ಭೂತೇಷು ವಿಭಕ್ತಮ್‌ ಇವ ಚ ಸ್ಥಿತಮ್‌ |\nಭೂತಭರ್ತೃ ಚ ತತ್‌ ಜ್ಞೇಯಮ್‌ ಗ್ರಸಿಷ್ಟು ಪ್ರಭವಿಷ್ಣು ಚ -ಎಲ್ಲಾ ಜೀವಿಗಳಲ್ಲು ಏಕರೂಪವಾಗಿದೆ; ಆದರೂ\nಬೇರೆಯೋ ಎನ್ನುವಂತೆ ಬಹುರೂಪದಿಂದಿದೆ. ಎಲ್ಲಾ ಜೀವಿಗಳನ್ನು ಪಾಲಿಸುವಂತಾದ್ದು; ಕಬಳಿಸುವಂತಾದ್ದು\nಮತ್ತು ಹುಟ್ಟಿ ಸುವಂತಾದ್ದು ಅದೇ ಎಂದು ತಿಳಿಯಬೇಕು.\n\nಭಗವಂತ ಈ ಪ್ರಪಂಚದಲ್ಲಿನ ಪ್ರತಿಯೊಂದು ಜೀವದಲ್ಲೂ ಬಿಂಬ ರೂಪನಾಗಿ ನೆಲೆಸಿದ್ದಾನೆ. ಒಂದೊಂದು\nಜೀವದಲ್ಲೂ ಅನೇಕ ರೂಪದಲ್ಲಿ ಆತನಿದ್ದಾನೆ. ಇಲ್ಲಿ ಪ್ರತಿಯೊಂದು ಜೀವಗಳೂ ವಿಭಕ್ತಗಳು. ಆದರೆ ಭಗವಂತ\nಮಾತ್ರ ಅಖಂಡ(ಅವಿಭಕ್ತ). ಎಲ್ಲಾ ಕಡೆ ಇರುವ ಭಗವಂತ ಒಬ್ಬನೆ ಆದರೆ ಬೇರೆ ಬೇರೆ ಇದ್ದಂತೆ ನಮಗೆ\nಕಾಣಿಸುತ್ತಾನೆ ಅಷ್ಟೆ. ಇದಕ್ಕೆ ಉತ್ತಮ ಉದಾಹರಣೆ ಭಗವಂತನ ಅವತಾರವಾದ-ಪರಶುರಾಮ, ವೇದವ್ಯಾಸ\nಮತ್ತು ಶ್ರೀಕೃಷ್ಣ. ಇಲ್ಲಿ ಭಗವಂತ ಮೂರು ರೂಪದಲ್ಲಿ ನಮಗೆ ಏಕ ಕಾಲದಲ್ಲಿ ಕಾಣಿಸಿಕೊಂಡ. ಒಂದೇ ಆದರೂ\nಕೂಡಾ ಮೂರಾಗಿ ನಮಗೆ ಆತ ಕಾಣಿಸಿಕೊಂಡ. ಆತ ಸಮಸ್ತ ಜೀವದೊಳಗಿದ್ದಾನೆ ಆದರೆ ಸಮಸ್ತ ಜೀವವನ್ನೂ\nಆತನೇ ಹೊತ್ತುಕೊಂಡಿದ್ದಾನೆ. ಎಲ್ಲರ ಸೃಷ್ಟಿಕರ್ತ ಭಗವಂತ ಹಾಗೂ ತನ್ನ ಸೃಷ್ಟಿಯನ್ನು ಒಂದು ದಿನ ಸಂಹಾರ\nಮಾಡುವವನೂ ಆತನೇ. ಸಂಹಾರದ ನಂತರ ಸೃಷ್ಟಿಯ ಪುನರ್ನಿರ್ಮಾಣ ಮಾಡುವವನೂ ಅವನೇ.\n",
  "13.17": "ಜ್ಯೋತಿಷಾಮ್‌ ಅಪಿ ತತ್‌ ಜ್ಯೋತಿಃ ತಮಸಃ ಪರಮ್‌ ಉಚ್ಯತೇ |\n\nಜ್ಞಾನಮ್‌ ಜ್ಞೇಯಮ್‌ ಜ್ಞಾನಗಮ್ಯಮ್‌ ಹೃದಿ ಸರ್ವಸ್ಯ ವಿಷ್ಠಿತಮ್‌ --ಅದು ಬೆಳಕುಗಳಿಗೆಲ್ಲ ಹಿರಿ ಬೆಳಕು.\nಕತ್ತಲೆಯ ಆಚೆಗಿರುವಂತಾದ್ದು. ಅದು ತಿಳಿವಿನ ರೂಪ. ತನ್ನನು ತಾನೇ ತಿಳಿವಂತಾದ್ದು. ತಿಳಿವಿನಿಂದ\nಪಡೆಯಬಹುದಾದಂತಾದ್ದು. ಎಲ್ಲರ ಹೃದಯದಲ್ಲೂ ನೆಲೆಸಿರುವಂತಾದ್ದು.\n\nಈವರೆಗೆ ಕೃಷ್ಣ ವಿವರಿಸಿದ ವಿಚಾರವನ್ನು ನಾವು ನಮ್ಮ ಧ್ಯಾನದಲ್ಲಿ ಕಾಣುವುದು ಕಷ್ಟ. ಅದಕ್ಕಾಗಿ ಕೃಷ್ಣ ಈ\nಶ್ಲೋಕದಲ್ಲಿ ತನ್ನನ್ನು ಭಾವನಾತ್ಮಕವಾಗಿ ವಿವರಿಸುತ್ತಾನೆ. ಭಗವಂತ ಕತ್ತಲಿಲ್ಲದ ಬೆಳಕು. ಆ ಬೆಳಕಿಗೆ ಒಂದು\nಅವಧಿ ಇಲ್ಲ. ಅದು ಅನಂತ. ಎಲ್ಲಾ ಬೆಳಕುಗಳಿಗೂ ಬೆಳಕು ಕೊಡುವ ಮಹಾಜ್ಯೋತಿ ಭಗವಂತ. ಭಗವಂತನನ್ನು\nಧ್ಯಾನದಲ್ಲಿ ಕಾಣಬೇಕು ಎಂದು ಕಣ್ಣು ಮುಚ್ಚಿ ಕುಳಿತಾಗ ನಮಗೆ ನಮ್ಮ ಇಷ್ಟವಾದ ವಸ್ತು ಅಥವಾ ವ್ಯಕ್ತಿ\nಕಾಣಬಹುದು. ಆಗ ಆ ವ್ಯಕ್ತಿಯೊಳಗೆ/ವಸ್ತುವಿನೊಳಗೆ ನಾವು ಭಗವಂತನನ್ನು ಕಾಣಲು ಪ್ರಯತ್ನಿಸಬೇಕು.\n(ಏಕೆಂದರೆ ಭಗವಂತ ಸರ್ವಾಂತರ್ಯಾಮಿ-ಆತ ಎಲ್ಲವುದರ ಒಳಗೂ ಹೊರಗೂ ತುಂಬಿ ನಿಂತಿದ್ದಾನೆ). ನಂತರ\n\"ಸೂರ್ಯನಲ್ಲಿ ಭಗವಂತನಿದ್ದಾನೆ, ಸೌರಶಕ್ತಿ ಆತನ ಕೊಡುಗೆ\" ಎಂದು ಅನುಸಂಧಾನ ಮಾಡಬೇಕು. ನಂತರ\nಸೌರಮಂಡಲದ ಮಧ್ಯದಲ್ಲಿ ಭಗವಂತನ ಪಾದವನ್ನು ಕಾಣುವ ಪ್ರಯತ್ನ ಮಾಡಬೇಕು. ಆ ಪಾದದ ಬೆರಳಿನ\n\nತುದಿಯಿಂದ ಚಿಮ್ಮಿದ ಬೆಳಕು ನಮ್ಮ ಹೃದಯವನ್ನು ಪ್ರವೇಶಿಸಿ ಬೆಳಗುತ್ತಿರುವುದನ್ನು ಧ್ಯಾನದಲ್ಲಿ ನಾವು\nಅನುಭವಿಸಬೇಕು. ಇದು ಧ್ಯಾನದಲ್ಲಿ ಹಂತ ಹಂತವಾಗಿ ನಾವು ಭಗವಂತನನ್ನು ಕಾಣುವ ಪ್ರಕ್ರಿಯೆ. ಭಗವಂತ ಈ\nಜಗತ್ತಿನ ಎಲ್ಲಾ ಬೆಳಕುಗಳಿಗೂ ಬೆಳಕು ಕೊಟ್ಟವ. ನಮ್ಮ ಅಂತರಂಗವನ್ನು ಬೆಳಗಿಸುವ ಸಾಮರ್ಥ್ಯ ಇರುವುದು\nಕೇವಲ ಭಗವಂತನಿಗೆ. ಭಗವಂತನೆಂಬ ಬೆಳಕು ಕತ್ತಲನ್ನು ಮೀರಿದ್ದು. ಅದು ಜ್ಞಾನಾನಂದಸ್ವರೂಪದ ಬೆಳಕು.\nಭಗವಂತನನ್ನು ಪೂರ್ಣ ತಿಳಿದವನು ಭಗವಂತನೊಬ್ಬನೇ. ನಾವು ಯಥಾಶಕ್ತಿ ಆತನನ್ನು ತಿಳಿಯುವ\nಪ್ರಯತ್ನವನ್ನು ಮಾಡಬೇಕು. ಭಗವಂತ ನಮ್ಮ ಹೃದಯದಲ್ಲೇ ನೆಲೆಸಿದ್ದಾನೆ. ಆತ ಎಲ್ಲಕ್ಕಿಂತ ವಿಲಕ್ಷಣನಾಗಿ\nನಮ್ಮ ಹೃತ್ಕಮಲ ಮಧ್ಯದಲ್ಲಿ ಸೂಕ್ಷಕ್ಕಿಂತ ಸೂಕ್ಷ್ಮನಾಗಿ ನೆಲೆಸಿದ್ದಾನೆ. ಇಂತಹ ಭಗವಂತನನ್ನು ನಾವು\nಭಕ್ತಿಪೂರ್ವಕ ಜ್ಞಾನದಿಂದ ಮಾತ್ರ ಅರಿಯಲು ಸಾಧ್ಯ.\n",
  "13.18": "ಇತಿ ಕ್ಷೇತ್ರಮ್‌ ತಥಾ ಜ್ಞಾನಮ್‌ ಜ್ಞೇಯಮ್‌ ಚ ಉಕ್ತಮ್‌ ಸಮಾಸತಃ |\nಮತ್‌ ಭಕ್ತಃ ಏತತ್‌ ವಿಜ್ಞಾಯ ಮತ್‌ ಭಾವಾಯ ಉಪದ್ಯತೇ -ಹೀಗೆ “ಕ್ಷೇತ್ರ”-“ಜ್ಞಾನ” ಮತ್ತು “ಜ್ಞೇಯ'ಗಳನ್ನು\nಅಡಕವಾಗಿ ಹೇಳಿದಂತಾಯಿತು. ನನ್ನ ಭಕ್ತನಾದವನು ಇದನ್ನರಿತು ನನ್ನಲ್ಲೇ ನೆಲೆಸುತ್ತಾನೆ.\n\nಈ ಶ್ಲೋಕದಲ್ಲಿ ಕೃಷ್ಣ ಈವರೆಗೆ ಹೇಳಿದ ವಿಚಾರದ ಉಪಸಂಹಾರ ಮಾಡುತ್ತಾ ಹೇಳುತ್ತಾನೆ: “ಈ ತನಕ ಕ್ಷೇತ್ರದ\nಬಗ್ಗೆ. ಜ್ಞಾನಸಾಧನಗಳ ಬಗ್ಗೆ, ಈ ಜ್ಞಾನ ಸಾಧನಗಳಿಂದ ತಿಳಿದುಕೊಳ್ಳಬೇಕಾದ ಭಗವಂತನ ಬಗ್ಗೆ\nಅಡಕವಾಗಿ(In a nutshell) ಹೇಳಿದ್ದಾಯಿತು. ಸೃಷ್ಟಿ, ಸೃಷ್ಟಿಯಾದ ಪ್ರಪಂಚ, ಪ್ರಪಂಚ ಸೃಷ್ಟಿಯ ಬಗೆ,\nಸ್ರಷ್ಟಾರನಾದ ಭಗವಂತ- ಇದನ್ನು ತಿಳಿದರೆ ಮತ್ತೆ ತಿಳಿಯಬೇಕಾದದ್ದು ಏನೂ ಉಳಿಯುವುದಿಲ್ಲ. ಪೂರ್ಣ\nನಂಬಿಕೆಯಿಂದ, ಭಕ್ತಿಯಿಂದ ಇದನ್ನು ಅರಿತ ಭಕ್ತ ನನ್ನನ್ನು ಸೇರುತ್ತಾನೆ” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಭಗವಂತನ ಬಗೆಗಿನ\nಜ್ಞಾನ ಮತ್ತು ಭಕ್ತಿ ನಮ್ಮನ್ನು ಮೋಕ್ಷದತ್ತ ಕೊಂಡೊಯ್ಯಬಲ್ಲದು.\n\nಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ಕೃಷ್ಣ ಮೂಲ ಸೃಷ್ಟಿಯ ಕಲ್ಪನೆ ಮತ್ತು ಅದರ ಅನುಸಂಧಾನವನ್ನು ವಿವರಿಸುತ್ತಾನೆ. ಈ\nಶ್ಲೋಕ ಅಧ್ಯಾತ್ಮ ಪ್ರಪಂಚದಲ್ಲಿ ಸೃಷ್ಟಿಯ ಬಗೆಗಿನ ಎಲ್ಲಾ ಗೊಂದಲಗಳಿಗೆ ಕೃಷ್ಣ ಕೊಟ್ಟ ಉತ್ತರ. ಅಡಕವಾಗಿ\nಎಲ್ಲವನ್ನು ಈ ಶ್ಲೋಕದ ಮೂಲಕ ಕೃಷ್ಣ ನಮ್ಮ ಮುಂದಿಟ್ಟಿದ್ದಾನೆ.\n",
  "13.19": "ಪ್ರಕೃತಿಮ್‌ ಪುರುಷಮ್‌ ಚ ಏವ ವಿದ್ಧಿ ಅನಾದೀ ಉಭೌ ಅಪಿ |\n\nವಿಕಾರಾನ್‌ ಚ ಗುಣಾನ್‌ ಚ ಏವ ವಿದ್ಧಿ ಪ್ರಕೃತಿ ಸಂಭವಾನ್‌ - ಪ್ರಕೃತಿ[ಜಡಪ್ರಕೃತಿ ಮತ್ತು ಚೇತನಪ್ರಕೃತಿ] ಮತ್ತು\nಪುರುಷ[ಜೀವ ಮತ್ತು ಈಶ್ವರ] ಇಬ್ಬರೂ ಹುಟ್ಟಿರದವರು ಎಂದು ತಿಳಿ. ಸ್ಥೂಲರೂಪಗಳು ಮತ್ತು ಗುಣತ್ರಯಗಳು\nಪ್ರಕೃತಿಯ ಕಾರ್ಯಗಳು ಎಂದು ತಿಳಿ.\n\nಭಗವಂತ ಯಾವುದೇ ಜೀವರನ್ನಾಗಲೀ, ಪ್ರಕೃತಿಯನ್ನಾಗಲೀ ಸೃಷ್ಟಿ ಮಾಡಿಲ್ಲ. ಜಡಪ್ರಕೃತಿ, ಚೇತನ ಪ್ರಕೃತಿ,\nಪರಮಪುರುಷ(ಭಗವಂತ), ಅವಾಂತರಪುರುಷರು(ಜೀವರು) ಎಲ್ಲರೂ ಅನಾಧಿನಿತ್ಯರು. ಪ್ರಪಂಚ ಎಂದರೆ\nಪ್ರಕೃತಿಯ ವಿಕಾರ. ಒಂದು ಮಗು ಹುಟ್ಟಿತು ಎಂದರೆ ಅಲ್ಲಿ ಆಗುವುದು ಜೀವದ ಸೃಷ್ಟಿ ಅಲ್ಲ. ಜೀವಕ್ಕೆ ಒಂದು\nಆಕಾರದ ಸೃಷ್ಟಿ. ಜೀವ ತಂದೆಯ ದೇಹದ ಮುಖೇನ ತಾಯಿಯ ಗರ್ಭವನ್ನು ಸೇರಿ ಅಲ್ಲಿ ಒಂದು ಆಕಾರವನ್ನು\nಪಡೆಯುತ್ತದೆ. ಈ ರೀತಿ. ಭಗವಂತ ಜೀವರಿಗೆ ಪ್ರಕೃತಿಯ ಮೂಲಕ ಒಂದು ಆಕಾರ ಸೃಷ್ಟಿ ಮಾಡುತ್ತಾನೆ.\nಸೃಷ್ಟಿಯ ಮೂಲದಲ್ಲೂ ಕೂಡಾ ಲಕ್ಷ್ಮೀನಾರಾಯಣರು ತಂದೆ-ತಾಯಿಯಾಗಿ ನಿಂತು ಪ್ರಪಂಚದ ಸೃಷ್ಟಿಗೆ\nಚಾಲನೆ ಕೊಟ್ಟರು. ಸೃಷ್ಟಿಯ ಆದಿಯಲ್ಲಿ ಜೀವರು ಲಕ್ಷ್ಮೀದೇವಿಯ ಉದರದಲ್ಲಿದ್ದರು. ಲಕ್ಷ್ಮೀದೇವಿ ಪರಮಪುರುಷ\nಭಗವಂತನ ಉದರದಲ್ಲಿದ್ದಳು. ಸೃಷ್ಟಿಯ ಮೂಲದಲ್ಲಿ ಲಕ್ಷ್ಮಿಯ ನೆತ್ತಿಯಿಂದ ಹೊರ ಹೊಮ್ಮಿ, ಭಗವಂತನ\nನಾಭಿಯ ಮುಖೇನ ಚತುರ್ಮುಖಬ್ರಹ್ಮನ ಜನನವಾಯಿತು. ಈ ಕಾರಣದಿಂದ ಚತುರ್ಮುಖ ಬ್ರಹ್ಮನನ್ನು\nಲಕ್ಷ್ಮಿಯ ಶಿರಸ್ಸಿನಿಂದ ಮತ್ತು ಭಗವಂತನ ನಾಭಿಯಿಂದ ಜನಿಸಿದವನು ಎಂದು ಕರೆಯುತ್ತಾರೆ. ಒಟ್ಟಿನಲ್ಲಿ\n“ಜಗತ್ತಿಗೆ ಕಾರಣವಾಗಿರುವ ಜಡಪ್ರಕೃತಿ ನಿತ್ಯ; ಆ ಜಡಪ್ರಕೃತಿಯಿಂದ ಆಕಾರಗೊಂಡು ಸೃಷ್ಟನಾದ ಜೀವನೂ\nನಿತ್ಯ; ಈ ಜಡಪ್ರಕೃತಿ ಮತ್ತು ಜೀವನಿಗೆ ಕಾರಣಪುರುಷನಾದಂತಹ ಲಕ್ಷ್ಮೀನಾರಾಯಣರೂ ನಿತ್ಯರು; ಪ್ರಪಂಚ\nಎಂದರೆ ಪ್ರಕೃತಿಯ ವಿಕಾರ”. ಇದು ಇಲ್ಲಿ ನಾವು ತಿಳಿದುಕೊಳ್ಳಬೇಕಾಗಿರುವ ಮುಖ್ಯ ವಿಚಾರ.\n\nಮೊತ್ತ ಮೊದಲು ಸೃಷ್ಟಿ ವಿಸ್ತಾರಕ್ಕೆ ಬೇಕಾದ ಶಕ್ತಿ ಸೃಷ್ಟಿಯಾಯಿತು. ಅದೇ ಪ್ರಕೃತಿಯ ಅತ್ಯಂತ ಸೂಕ್ಷ್ಮ\nವಿಕಾರವಾದ ಗುಣತ್ರಯಗಳು. ಈ ಶಕ್ತಿ ಕಂಪನದಿಂದ ಇಡೀ ಪ್ರಪಂಚ ನಿಷ್ಟನ್ನವಾಯಿತು. ಆಕಾರ ಕೊಟ್ಟಿದ್ದು\nತಾಯಿ ಲಕ್ಷ್ಮಿ; ಆಕಾರ ಪಡೆದದ್ದು ಜೀವರು; ಆಕಾರ ಕೊಡುವವ ನಾರಾಯಣ. ಈ ಕಾರಣದಿಂದ ಚತುರ್ಮುಖ\nಬ್ರಹ್ಮನಿಂದ ಹಿಡಿದು ಸಮಸ್ತ ದೇವಾದಿ ಜೀವರೂ ಲಕ್ಷ್ಮೀನಾರಾಯಣರ ಮಕ್ಕಳು.\n\nಮೇಲಿನ ಶ್ಲೋಕದಲ್ಲಿ ಕೃಷ್ಣ ಪುರುಷ ಮತ್ತು ಪ್ರಕೃತಿ ಬಗ್ಗೆ ಹೇಳಿದ. [ಪುರುಷ ಎಂದರೆ ಜೀವಾತ್ಮ ಮತ್ತು\nಪರಮಾತ್ಮ. ಪ್ರಕೃತಿ ಎಂದರೆ ಜಡಪ್ರಕೃತಿ ಮತ್ತು ಚೇತನ ಪ್ರಕೃತಿ]. ಸೃಷ್ಟಿ ಪ್ರಕ್ರಿಯೆಯಲ್ಲಿ ಈ ನಾಲ್ಕು ಪಾತ್ರದ\nವಿವರಣೆಯನ್ನು ಕೃಷ್ಣ ಮುಂದಿನ ಮೂರು ಶ್ಲೋಕಗಳಲ್ಲಿ ನಮ್ಮ ಮುಂದಿಟ್ಟಿದ್ದಾನೆ. ಮೊದಲ ಶ್ಲೋಕದಲ್ಲಿ(ಶ್ಲೋ-\n೨೦) ಕೃಷ್ಣ ಜೀವಾತ್ಮ-ಪರಮಾತ್ಮ, ಜ",
  "13.20": "ಕಾರ್ಯ ಕಾರಣ ಕರ್ತೃತ್ವೇ ಹೇತುಃ ಪ್ರಕೃತಿಃ ಉಚ್ಯತೇ |\n\nಪುರುಷಃ ಸುಖಃ ದುಃಖಾನಾಂ ಭೋಕ್ಪತ್ವೇ ಹೇತುಃ ಉಚ್ಯತೇ -ದೇಹ ಮತ್ತು ಇಂದ್ರಿಯಗಳ ನಿರ್ಮಾಣದಲ್ಲಿ\nಜಡಪ್ರಕೃತಿ[ಚೇತನಪ್ರಕೃತಿಯಾದ ಶ್ರೀ ತತ್ವ] ಕಾರಣವೆನಿಸಿದೆ. ಸುಖ-ದುಃಖಗಳ ಅನುಭವದಲ್ಲಿ\nಜೀರ್ನಪರಮಾತ ಟೆ ಕಾರಣಭೂತನಾಗಿದ್ದಾನೆ.\n\nಈ ಶ್ಲೋಕದಲ್ಲಿ ಎರಡು ವಿಚಾರವನ್ನು ಕೃಷ್ಣ ಬಿಡಿಸಿ ತೋರಿದ್ದಾನೆ. ನಮಗೆ ಒಂದು ದೇಹವಿದೆ. ದೇಹದಲ್ಲಿ ಸುಖ-\nದುಃಖ ಭೋಗವನ್ನು ಅನುಭವಿಸಲು ಐದು ಇಂದ್ರಿಯಗಳಿವೆ. ಹೀಗೆ ಶರೀರ, ಶರೀರದಲ್ಲಿ ಇಂದ್ರಿಯಗಳು-\nಇಂದ್ರಿಯಗಳ ಮೂಲಕ ಸುಖ-ದುಃಖ ಭೋಗ-ಇದು ಜೀವನ. ಜೀವನಿಗೆ ಅವನು ಹಿಂದೆ ಮಾಡಿದ\nಕರ್ಮಕ್ಕನುಗುಣವಾಗಿ ಕಾರ್ಯ ಕಾರಣಗಳ ಕರ್ತೃತ್ವ. ಅಂದರೆ ನಮ್ಮ ಕರ್ಮಕ್ಕನುಗುಣವಾಗಿ ಭಗವಂತ ಈ\nಜನ್ಮದಲ್ಲಿ ಒಂದು ರೂಪವನ್ನು ಕೊಟ್ಟ. ಈ ನಮ್ಮ ದೇಹ ರೂಪುಗೊಳ್ಳಲು ಅಧಿಷ್ಠಾನಕಾರಣ ನಮ್ಮ ತಂದೆ ತಾಯಿ.\nನಮ್ಮ ದೇಹ ಜಡಪ್ರಕೃತಿಯಿಂದಾಗಿದೆ. ತಾಯಿಯ ಹೊಟ್ಟೆಯಲ್ಲಿ ನಮಗೆ ಈ ರೂಪವನ್ನು ಕೊಟ್ಟವಳು ಜಗನ್ಮಾತೆ\nಶ್ರೀಲಕ್ಷ್ಮಿ. ಭಗವಂತನಿಗೆ ಅಂಗವಾಗಿ ಲಕ್ಷ್ಮಿ ದೇಹ ರಚನೆ ಮಾಡುತ್ತಾಳೆ. ಈ ರೀತಿ ದೇಹದ ಅಂಗಾಂಗ ಮತ್ತು\nಇಂದ್ರಿಯಗಳನ್ನು ಪಡೆದ ಜೀವ, ಅದರಿಂದ ಸುಖ-ದುಃಖದ ಭೋಗವನ್ನು ಅನುಭವಿಸುತ್ತದೆ. ಪರಮಪುರುಷ\nಭಗವಂತ ಜೀವನಿಗೆ ಸುಖ-ದುಃಖದ ಅನುಭವವನ್ನು ಕೊಡುತ್ತಾನೆ. ಹೀಗಾಗಿ ದೇಹರಚನೆಯಲ್ಲಿ ಚೇತನ ಮತ್ತು\nಜಡ ಪ್ರಕೃತಿ ಒಳಗೊಂಡರೆ, ಭಗವಂತ ಜೀವನಿಗೆ ಭೋಕ್ರತ್ವದ ಅನುಭವವನ್ನು ಸ್ವಯಂ ಅಂತರ್ಯಾಮಿಯಾಗಿ\nನಿಂತು ನೀಡುತ್ತಾನೆ.\n",
  "13.21": "ಪುರುಷಃ ಪ್ರಕೃತಿಸ್ಥಃ ಹಿ ಭುಂಕ್ತೇ ಪ್ರಕೃತಿಜಾನ್‌ ಗುಣಾನ್‌ |\n\nಕಾರಣಮ್‌ ಗುಣಸಂಗಃ ಅಸ್ಯ ಸತ್‌ ಅಸತ್‌ ಯೋನಿ ಜನ್ಮಸು -ಪ್ರಕೃತಿಯ ಕಟ್ಟಿಗೊಳಗಾದ ಜೀವ, ಪ್ರಕೃತಿ\nಕಾರ್ಯಗಳಾದ ಸುಖ-ದುಃಖಾದಿಗಳನ್ನು ಅನುಭವಿಸುತ್ತಾನೆ. ಒಳ್ಳೆಯ ಮತ್ತು ಕೆಟ್ಟ ಬಸಿರಿನಲ್ಲಿ ಹುಟ್ಟಿಬರಲು\nಜೀವನಿಗೆ ತ್ರಿಗುಣಗಳ ನಂಟೇ ಕಾರಣ.\n\nಪ್ರಕೃತಿ ನಿರ್ಮಿತವಾದ ದೇಹದಲ್ಲಿ ಭಗವಂತನಿದ್ದಾನೆ, ದೇವತೆಗಳಿದ್ದಾರೆ. ಆದರೆ ದೇಹದಲ್ಲಿದ್ದು ಸುಖ-ದುಃಖದ\nಭೋಗವನ್ನು ಅನುಭವಿಸುವವನು-ಜೀವ. ದೇಹ ಪ್ರಕೃತಿಯ ಗುಣದಿಂದ ನಿರ್ಮಾಣವಾಗಿರುತ್ತದೆ. ಜೀವ ತನ್ನ\nಸ್ವಭಾವಕ್ಕನುಗುಣವಾಗಿ, ಪೂರ್ವ ಜನ್ಮದ ಕರ್ಮಫಲಕ್ಕನುಗುಣವಾಗಿ ಈ ಜನ್ಮದಲ್ಲಿ ದೇಹವನ್ನು ಪಡೆಯುತ್ತದೆ.\n\nಹಿಂದೆ ಹೇಳಿದಂತೆ ಜೀವ ತನ್ನ ದೇಹವನ್ನು ಬಿಟ್ಟು ಹೊರಬರುವಾಗ ಯಾವುದನ್ನು ಗಾಢವಾಗಿ ನೆನೆಯುತ್ತದೋ -\nಅದಕ್ಕನುಗುಣವಾಗಿ ಅದರ ಮುಂದಿನ ಜನ್ಮ ನಿರ್ಧಾರವಾಗುತ್ತದೆ. ಉತ್ತಮ ಅಥವಾ ಹೀನ ಯೋನಿಯಲ್ಲಿ\nಹುಟ್ಟಿಬರಲು ಜೀವನಿಗೆ ತ್ರಿಗುಣಗಳ ನಂಟೇ ಕಾರಣ.",
  "13.22": "ಉಪದ್ರಷ್ಟಾ ಅನುಮಂತಾ ಚ ಭರ್ತಾ ಭೋಕ್ತಾ ಮಹೇಶ್ವರಃ |\n\nಪರಮಾತ್ಮ ಇತಿ ಚ ಅಪಿ ಉಕ್ತಃ ದೇಹೇ ಅಸ್ಮಿನ್‌ ಪುರುಷಃ ಪರಃ -ಎಲ್ಲದರ ಮೇಲಿದ್ದು ಎಲ್ಲವನು ನೋಡುವವನು,\nತನ್ನಿಷ್ಟದಂತೆ. ಎಲ್ಲವನು ನಡೆಸುವವನು, ಎಲ್ಲವನು ಹೊತ್ತವನು, ಸಾರವನುಣ್ಣುವವನು-ಸರ್ವಶಕ್ತನಾದ\nಪರಮಾತ್ಮ. ಅವನೇ ಈ ದೇಹದಲ್ಲಿ ಜೀವನ ಜೊತೆಗಿರುವ ಪರಮಪುರುಷ.\n\nಚಿತ್‌ ಪ್ರಕೃತಿ ಜಡಪ್ರಕೃತಿಯಿಂದ ದೇಹ ನಿರ್ಮಿಸುವಾಗ, ಜೀವ ಆ ದೇಹದಲ್ಲಿದ್ದು ಇಂದ್ರಿಯಗಳ ಮುಖೇನ ಸುಖ\nದುಃಖವನ್ನು ಭೋಗಿಸುವಾಗ- ಎಲ್ಲದಕ್ಕೂ ಪ್ರೇರಕನಾಗಿ, ಎಲ್ಲವುದಕ್ಕಿಂತ ಎತ್ತರದಲ್ಲಿದ್ದು ಎಲ್ಲವನ್ನೂ ಹತ್ತಿರದಿಂದ\nಸಾಕ್ಷಾತ್‌ ಕಾಣುವ ಭಗವಂತ ಪರಮಪುರುಷ. ಆತ ನಮ್ಮ ಕರ್ಮವನ್ನು ಬಲ್ಲವನು. ಯಾವ ರೀತಿಯ\nಕರ್ಮದಿಂದ ಏನಾಗಬೇಕು ಎಂದು ತಿಳಿದವನು. ಆತ ಒಳಗೆ ಕೂತು ಪ್ರೇರಣೆ ಮಾಡುವುದರಿಂದ ಈ ದೇಹ\nನಿಂತಿದೆ. ಆತ ಹೊರಟು ಹೋದರೆ ದೇಹ ಬಿದ್ದು ಹೋಗುತ್ತದೆ. ಆತ ನಮ್ಮೊಳಗಿದ್ದು ಯಾವ ದುಃಖದ ಸ್ಪರ್ಶವೂ\nಇಲ್ಲದೆ ಸದಾ ಆನಂದದಿಂದಿರುವ ಆನಂದ ಭೋಕ್ತ.",
  "13.23": "ಯಃ ಏವಮ್‌ ವೇತ್ತಿ ಪುರುಷಮ್‌ ಪ್ರಕೃತಿಮ್‌ ಚ ಗುಣೈಃ ಸಹ ।\nಸರ್ವಥಾ ವರ್ತಮಾನಃ ಅಪಿ ನ ಸಃ ಭೂಯಃ ಅಭಿಜಾಯತೇ -ಹೀಗೆ ಪ್ರಕೃತಿ-ಪುರುಷರನ್ನು ಗುಣಗಳ ಜತೆಗೆ\nಅರಿತವನು ಹೇಗೆ ಬದುಕಿದರೂ ಮತ್ತೆ ಮರಳಿ ಹುಟ್ಟುವುದಿಲ್ಲ.\n\nಅನಾಧಿನಿತ್ಯವಾದ ಪ್ರಕೃತಿ(ಜಡ ಮತ್ತು ಚೇತನ), ಎಲ್ಲವುದಕ್ಕೂ ಕಾರಣ ಪುರುಷನಾದ ಪರಮಾತ್ಮ, ಆತನ\nಅಧೀನವಾಗಿರುವ ಜೀವಜಾತ ಇದನ್ನು ಗುಣಗಳ ಜೊತೆಗೆ ಅರಿತವನು ಜ್ಞಾನಿ. ಇಂತಹ ಜ್ಞಾನಿ ಬಾಹ್ಯವಾಗಿ ಹೇಗೆ\nಕಾಣಿಸಿಕೊಂಡರೂ ಕೂಡಾ, ಸತ್ಯದ ಸಾಕ್ಷಾತ್ಕಾರದಿಂದ ಆತ ಮೋಕ್ಷವನ್ನು ತಲುಪುತ್ತಾನೆ. ಇಲ್ಲಿ ಬಾಹ್ಯ\nಸಂಸ್ಕಾರಕ್ಕಿಂತ ಜ್ಞಾನ ಎಷ್ಟು ಮುಖ್ಯ ಎನ್ನುವುದನ್ನು ಕೃಷ್ಣ ಒತ್ತಿ ಹೇಳಿದ್ದಾನೆ. ಮುಖವಾಡದ ಬದುಕಿನಿಂದ ಏನೂ\nಉಪಯೋಗವಿಲ್ಲ. ಅದಕ್ಕಿಂತ ಮಿಗಿಲಾದದ್ದು ಸತ್ಯದ ಸಾಕ್ಷಾತ್ಕಾರ. ಸತ್ಯದ ಸಾಕ್ಷಾತ್ಕಾರವಾದಾಗ\n\nತಾನಾಗಿಯೇ ಲೌಕಿಕ ಪ್ರಪಂಚ ಎಷ್ಟು ಅರ್ಥಹೀನ ಎನ್ನುವುದು ತಿಳಿಯುತ್ತದೆ. ಜ್ಞಾನಕ್ಕಿಂತ ಮಿಗಿಲಾದ\nಇನ್ನೊಂದು ಪವಿತ್ರಸಾಧನವಿಲ್ಲ. ಕರ್ಮಾನುಷ್ಠಾನದಲ್ಲಿ ಅಕಾಸ್ಮಾತ್‌ ಚ್ಯುತಿಯಾದರೂ ಜ್ಞಾನ ಮಾರ್ಗದಲ್ಲಿ\nಸಾಗುವವನಿಗೆ ಅದು ಬಾಧಕವಾಗುವುದಿಲ್ಲ. ಜ್ಞಾನ ಅವನನ್ನು ಸರಿದಾರಿಗೆ ತಂದು ನಿಲ್ಲಿಸುತ್ತದೆ ಮತ್ತು ಆತ\nಮೋಕ್ಷವನ್ನು ಪಡೆಯುತ್ತಾನೆ.\n\nಕೃಷ್ಣ ಪ್ರಕೃತಿ ಮತ್ತು ಪುರುಷನನ್ನು ಗುಣ ಸಹಿತ ತಿಳಿಯುವುದು ಮೋಕ್ಷಮಾರ್ಗ ಎಂದು ಹೇಳಿದ. ಹಾಗಿದ್ದರೆ\nಇದನ್ನು ತಿಳಿಯುವ ಬಗೆ ಯಾವುದು? ಇದನ್ನು ಕೃಷ್ಣ ಮುಂದಿನ ಎರಡು ಶ್ಲೋಕಗಳಲ್ಲಿ ವಿವರಿಸುತ್ತಾನೆ.\nಭಗವಂತನನ್ನು ಸೇರಲು ಅನೇಕ ವಿಧಾನಗಳಿವೆ. ಎಲ್ಲರಿಗೂ ಎಲ್ಲವೂ ಅಲ್ಲ. ಏಕೆಂದರೆ ಒಬ್ಬರು ತಿಳಿದಂತೆ\nಇನ್ನೊಬ್ಬರು ತಿಳಿದುಕೊಳ್ಳಲು ಆಗುವುದಿಲ್ಲ. ಬನ್ನಿ ಈ ಕುರಿತು ಕೃಷ್ಣನ ವಿವರಣೆಯನ್ನು ಆಲಿಸೋಣ.\n",
  "13.24": "ಧ್ಯಾನೇನ ಆತ್ಮನಿ ಪಶ್ಯಂತಿ ಕೇಚಿತ್‌ ಆತ್ಮಾನಮ್‌ ಆತ್ಮನಾ |\nಅನ್ಯೇ ಸಾಂಖ್ಯೇನ ಯೋಗೇನ ಕರ್ಮಯೋಗೇನ ಚ ಅಪರೇ -ಕೆಲವರು ಧ್ಯಾನದ ಮೂಲಕ ಪರಮಾತ್ಮನನ್ನು\nತನ್ನಲ್ಲಿ ಬಗೆಗಣ್ಣಿನಿಂದ ಕಾಣುತ್ತಾರೆ. ಕೆಲವರು ಶಾಸ್ತ್ರದ ಅರಿವಿನ ಮೂಲಕ. ಕೆಲವರು ಕರ್ಮಯೋಗದ ಮೂಲಕ.\n\nಸಾಧನೆ ಮಾಡಲು ಮೊದಲು ನಮಗೆ ಸಾಧನಾ ಶರೀರ ಬೇಕು. ಹೀನಯೋನಿಯಲ್ಲಿ ಪೂರ್ಣತೆ ಪಡೆಯದ\nಶರೀರದಲ್ಲಿ ಹುಟ್ಟಿ ಬಂದರೆ ಸಾಧನೆ ಸಾಧ್ಯವಿಲ್ಲ. ಮೊದಲು ನಾವು ಮಾನವರಾಗಬೇಕು(ಪೂರ್ಣತೆಯನ್ನು ಪಡೆದ\nಶರೀರದಲ್ಲಿ ನೆಲೆಸುವ ಪುರುಷರಾಗಬೇಕು). ಇದಕ್ಕಾಗಿ \"ಮಾನವ ಜನ್ಮ ದೊಡ್ಡದು, ಅದನ್ನು ಹಾಳು ಮಾಡಿ\nಕೊಳ್ಳದಿರಿ ಹುಚ್ಚಪ್ಪಗಳಿರಾ! \"ಎಂದು ದಾಸರು ಹಾಡಿರುವುದು. ಸಾಧನೆಗೆ ಬೇಕಾದ ಸಾಧನಾ ಶರೀರ ಇಲ್ಲದಿದ್ದರೆ\nಯಾವಸಾಧನೆಯೂ ಸಾಧ್ಯವಿಲ್ಲ.\n\nಕೆಲವರು ತಮ್ಮ ಸ್ವರೂಪ ಯೋಗ್ಯತೆಯಿಂದ ಮತ್ತು ಭಗವದನುಗ್ರಹದಿಂದ ಜನ್ಮತಃ ಜ್ಞಾನ ಪಡೆದು ಹುಟ್ಟುತ್ತಾರೆ.\nಇವರಿಗೆ ಜ್ಞಾನ ನಿಚ್ಚಳ. ಇಂತವರು ತಮ್ಮ ಜೀವ ಯೋಗ್ಯತೆಯಿಂದ ತಮ್ಮ ಜೀವ ಸ್ವರೂಪದೊಳಗೆ- ಬಿಂಬರೂಪಿ\nಭಗವಂತನನ್ನು ಕಾಣಬಲ್ಲರು. ಇಂತವರು ಯಾವುದೇ ಅಧ್ಯಯನ ಮಾಡದೆ ಸದಾ ಭಗವಂತನನ್ನು\nಅಂತರಂಗದಲ್ಲಿ ಕಾಣುತ್ತಾ-ಭಗವಂತನನ್ನು ಸೇರುತ್ತಾರೆ. ಬ್ರಹ್ಮಾದಿ ಸಕಲ ದೇವತೆಗಳು, ದೇವಾಂಶ\nಸಂಭೂತರು ಈ ರೀತಿ ಕಣ್ಮುಚ್ಚಿ ಭಗವಂತನನ್ನು ಕಾಣಬಲ್ಲರು, ಕಂಡು ಆತನನ್ನು ಸೇರಬಲ್ಲರು.\n\nಕೆಲವರು ಶುದ್ಧ ಆತ್ಮತತ್ವ ವಿಜ್ಞಾನದಿಂದ ಮೊದಲು ಭಗವಂತನನ್ನು ತಿಳಿಯುತ್ತಾರೆ. ಜೀವನನ್ನು,\nಪರಮಾತ್ಮನನ್ನು ತಿಳಿಯುವುದೇ ಸಾಂಖ್ಯಯೋಗ. ಈ ರೀತಿ ಜ್ಞಾನಗಳಿಸಿ, ಜ್ಞಾನಸ್ಪುರಣವನ್ನು ಗಳಿಸಿ, ಧ್ಯಾನದ\nಮೂಲಕ ಇವರು ಭಗವಂತನನ್ನು ಕಂಡು ಭಗವಂತನನ್ನು ಸೇರುತ್ತಾರೆ.\n\nಇನ್ನು ಕೆಲವರು ತಮ್ಮ ನಿರಂತರ ಕರ್ಮಾನುಷ್ಠಾನದಿಂದ ದೇಹ ಶುದ್ಧಿ ಸಾಧಿಸಿ, ಅದರಿಂದ ಭಗವಂತನ\nಒಲುಮೆಗೆ ಪಾತ್ರರಾಗಿ, ಜ್ಞಾನಗಳಿಸಿ, ಧ್ಯಾನದಲ್ಲಿ ಭಗವಂತನನ್ನು ಕಂಡು ಭಗವಂತನನ್ನು ಸೇರುತ್ತಾರೆ.",
  "13.25": "ಅನ್ಯೇ ತು ಏವಂ ಅಜಾನಂತಃ ಶ್ರುತ್ವಾ ಅನ್ಯೇಭ್ಯಃ ಉಪಾಸತೇ ।\n\nತೇ ಅಪಿ ಚ ಅತಿತರಂತಿ ಏವ ಮೃತ್ಯುಮ್‌ ಶ್ರುತಿಪರಾಯಣಾಃ -ಹೀಗೆ ಭಗವಂತನನ್ನರಿಯಲಾರದ ಇನ್ನು\nಕೆಲವರು ಬಲ್ಲವರಿಂದ ಕೇಳಿ ಉಪಾಸನೆ ಮಾಡುತ್ತಾರೆ. ಶ್ರವಣವನ್ನೇ ನಂಬಿ ನಡೆವ ಅವರೂ ಸಾಧನೆಯಿಂದ\nಬೆಳೆದು ಸಾವನ್ನು ಗೆಲ್ಲುತ್ತಾರೆ.\n\nಜನಸಾಮಾನ್ಯರು, ಮೇಲಿನ ಯಾವ ವಿಧದಲ್ಲೂ ಸಾಧನೆ ಮಾಡಲಾರದವರು-ಇನ್ನೊಬ್ಬರಿಂದ ಕೇಳಿ ತಿಳಿದು\nಸಾಧನೆಯ ಮೊದಲ ಮೆಟ್ಟಿಲನ್ನು ಹತ್ತಬಲ್ಲರು. ಇದು ಸಾಧನೆಯ ಮಾರ್ಗದಲ್ಲಿನ ಅತ್ಯಂತ ಕೆಳಗಿನ\nಮೆಟ್ಟಿಲಾದರೂ ಸಹ, ಇವರು ನಿರಂತರ ಶ್ರವಣ, ಮನನ, ನಿಧಿಧ್ಯಾಸನದಿಂದ, ಅಹಂಕಾರವಿಲ್ಲದೆ, ಜ್ಞಾನ\nಸಂಪಾದಿಸಿ, ಆ ಜ್ಞಾನದಿಂದ-ಧ್ಯಾನದಲ್ಲಿ ಭಗವಂತನನ್ನು ಕಾಣಬಲ್ಲರು. ಇದು ಸಾಮಾನ್ಯ ಮಾನವನಿಗೆ ಕೃಷ್ಣ\nತೋರಿಸಿದ ಮೋಕ್ಷ ಮಾರ್ಗ. ಹೀಗೆ ಇವರು ಶ್ರವಣ ಮತ್ತು ಉಪಾಸನೆಯಿಂದ ಮೃತ್ಯುವನ್ನು ಗೆದ್ದು\nಭಗವಂತನನ್ನು ಸೇರಬಲ್ಲರು.",
  "13.26": "ಯಾವತ್‌ ಸಂಜಾಯತೇ ಕಿಂಚಿತ್‌ ಸತ್ವಮ್‌ ಸ್ಥಾವರ ಜಂಗಮಮ್‌ |\nಕ್ಷೇತ್ರ ಕ್ಷೇತ್ರಜ್ಞ ಸಂಯೋಗಾತ್‌ ತತ್‌ ವಿದ್ಧಿ ಭರತರ್ಷಭ -- ಭರತರ್ಷಭಾ, ಸ್ಥಿರ-ಚರ ಜೀವಿಯಲ್ಲಿ ಯಾವುದು\nಹುಟ್ಟಿದರೂ ಅದು ಕ್ಷೇತ್ರ[ಶ್ರೀತತ್ವ] ಮತ್ತು ಕ್ಷೇತ್ರಜ್ಞನಾದ ಭಗವಂತನ ಸಹಯೋಗದಿಂದಲೇ ಎಂದು ತಿಳಿ.\n\nಈ ಪ್ರಪಂಚದಲ್ಲಿ ಏನೆಲ್ಲಾ ಹುಟ್ಟುತ್ತದೋ, ಚಲಿಸುವ-ಚಲಿಸದಿರುವ ಸಮಸ್ತ ಜೀವ ಜಡಾತ್ಮಕ ಪ್ರಪಂಚ ಮತ್ತು\nಅದರ ಅಭಿಮಾನಿನಿಯಾದ ಪ್ರಕೃತಿದೇವಿ-ಇಷ್ಟನ್ನು ಒಟ್ಟಿಗೆ ಕ್ಷೇತ್ರವೆನ್ನುತ್ತಾರೆ. ಇವೆಲ್ಲವನ್ನು ಬಲ್ಲವ\nಕ್ಷೇತ್ರಜ್ಞನಾದ ಭಗವಂತ. ಆದ್ದರಿಂದ ಕ್ಷೇತ್ರವೆಂದರೆ ಭಗವಂತನಿಂದ ನಿರ್ಮಾಣವಾದ ಸಮಸ್ತ ಜೀವ ಜಡಾತ್ಮಕ\nಪ್ರಪಂಚ. ಸಮಸ್ತ ಸೃಷ್ಟಿ ಲಕ್ಷ್ಮೀ ನಾರಾಯಣರ ಸಮಾಗಮದಿಂದ ನಿರ್ಮಾಣವಾಯಿತು. ಅವರು ಈ ಪ್ರಪಂಚದ\nಮೊದಲ ದಂಪತಿಗಳು. ಆದ್ದರಿಂದ ಎಲ್ಲರ ತಂದೆ ತಾಯಿ ನಾರಾಯಣ ಮತ್ತು ಶ್ರೀಲಕ್ಷ್ಮಿ. “ಇದನ್ನು ತಿಳಿದಾಗ\n\nನೀನು ನಿಜವಾದ ಭರತರ್ಷಭನಾಗುತ್ತೀಯ” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಭಗವಂತನಲ್ಲಿ ರಥನಾದವನು, ಭಗವಂತನಲ್ಲಿ\nಪೂರ್ಣಭಕ್ತಿ ಉಳ್ಳವನು ಭರತರ್ಷಭ.\n",
  "13.27": "ಸಮಮ್‌ ಸರ್ವೇಷು ಭೂತೇಷು ತಿಷ್ಠಂತಂ ಪರಮೇಶ್ವರಮ್‌ ।\n\nವಿನಶ್ಯತ್ಸು ಅವಿನಶ್ಯಂತಂ ಯಃ ಪಶ್ಯತಿ ಸಃ ಪಶ್ಯತಿ - ಎಲ್ಲಾ ಜೀವಿಗಳಲ್ಲೂ ಏಕರೂಪದಿಂದಿರುವವನು\nಸರ್ವಶಕ್ತನಾದ ಭಗವಂತ-ಅವು ಅಳಿದಾಗಲೂ ಅಳಿಯದೇ ಉಳಿದವನು. ಅವನನ್ನು ತಿಳಿದವನೇ \"ನಿಜವಾಗಿ\nತಿಳಿದವನು”,\n\nಎಲ್ಲಾ ಜೀವರೊಳಗೂ ಏಕರೂಪದಿಂದಿರುವ ಸರ್ವಶಕ್ತ ಭಗವಂತ ಪರಮ-ಈಶ-ವರ. ಯಾರ ಆಜ್ಞೆಯನ್ನು ನಾವು\nಪಾಲಿಸದೇ ಇರಲಾರೆವೋ; ಪಾಲಿಸುವುದು ನಮ್ಮ ಕರ್ತವ್ಯವೋ; ನಮಗರಿವಿಲ್ಲದೇ ನಮ್ಮೊಳಗಿದ್ದು ಪಾಲಿಸುವ\nಅಜ್ಞಾತಶಕ್ತಿ- \"ಈಶ-ವರ'. ಅಂದರೆ ತತ್ತ್ವಾಭಿಮಾನಿ ದೇವತೆಗಳು. ಇಂತಹ ತತ್ತ್ವಾಭಿಮಾನಿ ದೇವತೆಗಳನ್ನೂ\nನಿಯಂತ್ರಿಸುವ ಭಗವಂತ ಪರಮೇಶ್ವರ. ಇಂತಹ ಭಗವಂತ ಎಲ್ಲೋ ಕೂತು ನಮ್ಮನ್ನು ನಿಯಮಿಸುತ್ತಿಲ್ಲ. ಆತ\nನಮ್ಮೊಳಗಿದ್ದು ನಮ್ಮನ್ನು ನಿಯಂತ್ರಿಸುತ್ತಿದ್ದಾನೆ. ಆತ ನಮ್ಮೊಳಗೆ ಸ್ವತಂತ್ರವಾಗಿದ್ದು ನಮ್ಮನ್ನು ಹೊತ್ತು\nನಡೆಸುತ್ತಿದ್ದಾನೆ [ಹಿಂದಿನ ಕಾಲದವರು ಜನರಿಗೆ ಈ ಸಂದೇಶವನ್ನು ದೇವಸ್ಥಾನದಲ್ಲಿ ತಟ್ಟಿರಾಯನ ಮೂಲಕ\nಕೊಟ್ಟರು]... ಭಗವಂತ ಮುಕ್ತಾ56ಮುಕ್ತ ನಿಯಾಮಕ. ಎಲ್ಲರನ್ನೂ ಎಲ್ಲಾ ಕಾಲದಲ್ಲಿ ಅವರವರ\nಯೋಗ್ಯತೆಗನುಗುಣವಾಗಿ, ಆಯಾ ವಸ್ತುವಿನ ಸ್ವಭಾವಕ್ಕನುಗುಣವಾಗಿ ಒಳಗಿದ್ದು ಪ್ರೇರಣೆ ಮಾಡುವವ\nಭಗವಂತ. ಭಗವಂತನ ಶಕ್ತಿಯಲ್ಲಿ ಮೇಲು ಕೀಳು ಇಲ್ಲ. ಆನೆಯಲ್ಲಿರುವ ಭಗವಂತ ಇರುವೆಯಲ್ಲಿರುವ ಭಗವಂತ\nಬೇರೆಬೇರೆ ಅಲ್ಲ. ಆದರೆ ಆತನ ಸನ್ನಿಧಾನದಲ್ಲಿ ವ್ಯತ್ಯಾಸವಿರುವುದರಿಂದ ಆ ಸನ್ನಿಧಾನದ ಅಧಿಷ್ಠಾನದಲ್ಲಿ\nವ್ಯತ್ಯಾಸ ಬರುತ್ತದೆ. ನಮ್ಮ ದೇಹದಲ್ಲಿರುವ ಬಿಂಬ ರೂಪಿ ಭಗವಂತ ಅವಿನಾಶಿ. ಆತನಿಗೆ ದೇಹನಾಶ,\nಸ್ವರೂಪನಾಶವಿಲ್ಲ. ದುಃಖಪ್ರಾಪ್ತಿ ಇಲ್ಲ. ಆತ ಅಪೂರ್ಣನಲ್ಲ. ಈ ಸತ್ಯವನ್ನು ತಿಳಿದವನು ಯಥಾರ್ಥ\nಜ್ಞಾನವುಳ್ಳವನು. ಈ ಶ್ಲೋಕದಲ್ಲಿ ಹೇಳಿದ ವಿಚಾರವನ್ನು ಇನ್ನೂ ಬಿಡಿಸಿ ಮತ್ತೆ ಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ಕೃಷ್ಣ\nವಿವರಿಸುತ್ತಾನೆ:\n",
  "13.28": "ಸಮಮ್‌ ಪಶ್ಯನ್‌ ಹಿ ಸರ್ವತ್ರ ಸಮವಸ್ಥಿತಮ್‌ ಈಶ್ವರಮ್‌ |\n\nನ ಹಿನಸ್ತಿ ಆತ್ಮನಾ ಆತ್ಮನಮ್‌ ತತಃ ಯಾತಿ ಪರಾಮ್‌ ಗತಿಮ್‌ - ಸರ್ವ ಶಕ್ತನಾದ ಭಗವಂತ ಎಲ್ಲೆಡೆಯೂ\nಏರುಪೇರಿಲ್ಲದೆ.. ಏಕರೂಪನಾಗಿದ್ದಾನೆ... ಎಂದು. ತಿಳಿದವನು ತನ್ನ ಏಳಿಗೆಗೆ ತಾನೇ ತಾನು\nಅಡ್ಡಿಯನೊಡ್ಡಿಕೊಳ್ಳುವುದಿಲ್ಲ. ಮುಂದೆ ಪರಮ ಪದವನ್ನು ಪಡೆಯುತ್ತಾನೆ.\n\nನಾವು ನಮ್ಮ ದೇಹದಲ್ಲಿ ಸ್ಥಿತರು. ಆದರೆ ಭಗವಂತ “ಸಂಸ್ಥಿತ'. ಈ ದೇಹದೊಳಗಿರುವ ನಮಗೆ ಈ ದೇಹದ\nಜ್ಞಾನ ಕೂಡಾ ಇಲ್ಲ. ಏಕಿದ್ದೇವೆ ಎಂದೂ ಗೊತ್ತಿಲ್ಲ. ನಾವು ಒಳಗಿದ್ದು ಆನಂದ ದುಃಖವನ್ನು ಅನುಭವಿಸುತ್ತಿರುತ್ತೇವೆ.\nಆದರೆ ಭಗವಂತ ದುಃಖ ಅಜ್ಞಾನದ ಸ್ಪರ್ಶವಿಲ್ಲದ ಆನಂದಮೂರ್ತಿ. ಆತ ನಮ್ಮೊಳಗಿರುವ ಸರ್ವ ತತ್ತ್ವಾಭಿಮಾನಿ\nದೇವತೆಗಳಿಗೆ ಸಮವಸ್ಥಿತನಾಗಿ ಎತ್ತರದಲ್ಲಿದ್ದಾನೆ. ದುಃಖ ಅಜ್ಞಾನದ ಸ್ಪರ್ಶವಿಲ್ಲದ ಭಗವಂತ ಯಾರನ್ನೂ\nಮೇಲು-ಕೀಳು ಭಾವದಿಂದ ನೋಡುವುದಿಲ್ಲ. ಪ್ರತಿಯೊಬ್ಬರನ್ನೂ ಅವರವರ ಕರ್ಮ ಮತ್ತು ಜೀವಯೋಗ್ಯತೆಗೆ\nತಕ್ಕಂತೆ ಸಮನಾಗಿ ಕಾಣುತ್ತಾನೆ. ಭಗವಂತ ಸಮಸ್ತ ಜಡ-ಚೇತನದೊಳಗೆ ಜಗದೀಶ್ವರನಾಗಿ ನಿಂತು ನಮ್ಮ\nಜೀವ ಸ್ವಭಾವಕ್ಕೆ ತಕ್ಕಂತೆ, ಕರ್ಮಕ್ಕನುಗುಣವಾಗಿ ನಮ್ಮನ್ನು ನಡೆಸುತ್ತಿದ್ದಾನೆ. ಈ ಸತ್ಯ ತಿಳಿದಾಗ “ನೀನು\nನಿನಗೆ ಹಿಂಸೆ ಮಾಡದೆ ಬದುಕಬಹುದು” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ನಿನ್ನ ಅರಿವಿಲ್ಲದೆ, ಭಗವಂತನ ಅರಿವಿಲ್ಲದೆ\nಬದುಕುವುದು ಒಂದು ಆತ್ಮಹಿಂಸೆ. ಒಮ್ಮೆ “ನಾನು' ಅಂದರೇನು, ನನ್ನೊಳಗಿರುವ ಭಗವಂತನೆಂದರೇನು ಎನ್ನುವ\nವಸ್ತುಃಸ್ಥಿತಿ ತಿಳಿದರೆ ಹಿಂಸೆಯಾಗುವುದಿಲ್ಲ. ಅದು ತಿಳಿಯದೆ ಬದುಕುವುದು ಅಜ್ಞಾನದ ಮತ್ತು ದುಃಖದ ಬದುಕು.\nಜೀವನದಲ್ಲಿ ಬರುವ ಪ್ರತಿಯೊಂದು ಸಂಗತಿಯನ್ನು-“ನಾನು ಹಿಂದೆ ಮಾಡಿದ ಕರ್ಮದ ಫಲ-ಅದನ್ನು ಭಗವಂತ\nಮಾಡಿಸಿದ” ಎಂದು ತಿಳಿದುಕೊಂಡರೆ ದುಃಖವಿಲ್ಲದೆ ಆನಂದದಿಂದ ಬದುಕಬಹುದು. ನಮ್ಮ ಮನಸ್ಸೇ ನಮಗೆ\nದುಃಖ ಕೊಡುವುದು. ಅದೇ ಆನಂದ ಕೊಡುವುದು. ನಮಗೆ ದುಃಖವಾಗುವುದು ನಮ್ಮ ತಿಳುವಳಿಕೆಯಿಂದಲೇ\nಹೊರತು ಇನ್ಯಾವುದರಿಂದಲೂ ಅಲ್ಲ. ಉದಾಹರಣೆಗೆ ಒಬ್ಬ ಶ್ರೀಮಂತ ಯಾವುದೋ ಕಾರಣದಿಂದ ತನ್ನ ಲ್ಲಿರುವ\nಎಲ್ಲಾ ಸಂಪತ್ತನ್ನು ಕಳೆದುಕೊಳ್ಳುತ್ತಾನೆ. ಆಗ ಆತ “ನನ್ನ ಪೂರ್ವ ಜನ್ಮದ ಕರ್ಮಕ್ಕನುಗುಣವಾಗಿ ಈ ಘಟನೆ\nನಡೆಯಿತು. ಎಲ್ಲವೂ ಭಗವಂತನ ಲೀಲೆ; ಕೊಡುವವನೂ ಅವನೇ, ತೆಗೆದುಕೊಳ್ಳುವವನೂ ಅವನೇ;\nಪಾಲಿಸುವವನೂ ಅವನೇ; ಇದಕ್ಕಾಗಿ ನಾನೇಕೆ ಚಿಂತಿಸಬೇಕು” ಎಂದು ತಿಳಿದುಕೊಂಡರೆ ಆತ\nಆನಂದದಿಂದಿರಬಹುದು. ಇದನ್ನು ಬಿಟ್ಟು ಬ್ರಹ್ಮಾಂಡವೇ ತಲೆಮೇಲೆ ಬಿದ್ದಂತೆ ವರ್ತಿಸಿದರೆ ಅದು ನಮ್ಮನ್ನು\nನಾವು ಹಿಂಸಿಸಿಕೊಂಡಂತೆ. ನಾವು ಎಲ್ಲವನ್ನು ಪ್ರೇಕ್ಷಕರಾಗಿ ಕಾಣಲು ಅಭ್ಯಾಸ ಮಾಡಿಕೊಳ್ಳಬೇಕು. ಭಗವಂತನ\nಅರಿವಿನೊಂದಿಗೆ ಶಾಂತವಾದ ಇಂತಹ ಬದುಕು ನಮ್ಮನ್ನು ಪರಮಪದವಾದ ಮೋಕ್ಷದತ್ತ ಕೊಂಡೊಯ್ಯಬಲ್ಲದು.\n\nಭಗವಂತನ ಚಿಂತನೆಯ ಇನ್ನೊಂದು ಅನುಸಂಧಾನವನ್ನು ಕೃಷ್ಣ ಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ನಮ್ಮ ಮುಂದಿಟ್ಟಿದ್ದಾನೆ.\nಎಚ್ಚರಿಕೆಯಿಂದ ಈ ಶ್ಲೋಕವನ್ನು ನಾವು ನೋಡಿದರೆ ನಮಗೆ ಸತ್ಯ ತಿಳಿಯುತ್ತದೆ. ನಮ್ಮಲ್ಲಿ ಎಲ್ಲರಲ್ಲೂ ಇರುವ\nಒಂದು ಗೊಂದಲ ಎಂದರೆ- “ಕ್ರಿಯೆಯನ್ನು ನಾನು ಮಾಡುವುದೇ ಅಥವಾ ನನ್ನಿಂದ ಭಗವಂತ ಮಾಡಿಸುವುದೇ?\nಭಗವಂತ ಮಾಡಿಸುವುದಾದರೆ ಏಕೆ ನನ್ನಿಂದ ಕೆಟ್ಟ ಕೆಲಸವನ್ನು ಮಾಡಿಸುತ್ತಾನೆ?”ಎಂಬುದು. ಈ ಪ್ರಶ್ನೆಗೆ ಕೃಷ್ಣ\nಈ ಶ್ಲೋಕದಲ್ಲಿ ಅಡಕವಾಗಿ ಉತ್ತರ ಕೊಟ್ಟಿದ್ದಾನೆ. ಇಲ್ಲಿ ಹಿಂದೆ. ಕೃಷ್ಣ ಹೇಳಿದ ವಿಚಾರವನ್ನು\nಗಮನದಲ್ಲಿಟ್ಟುಕೊಂಡು ಈ ಶ್ಲೋಕವನ್ನು ನಾವು ನೋಡಬೇಕಾಗಿದೆ.",
  "13.29": "ಪ್ರಕೃತ್ಯಾ ಏವ ಚ ಕರ್ಮಾಣಿ ಕ್ರಿಯಮಾಣಾನಿ ಸರ್ವಶಃ |\n\nಯಃ ಪಶ್ಯತಿ ತಥಾ ಆತ್ಮಾನಮ್‌ ಅಕರ್ತಾರಮ್‌ ಸಃ ಪಶ್ಯತಿ -- ಪ್ರಕೃತಿಯಿಂದಲೇ ಎಲ್ಲಾ ಕಾರ್ಯಗಳೂ\nನಡೆಯುತ್ತಿವೆ[ಜೀವನ ಕರ್ಮಕ್ಕನುಗುಣವಾಗಿ ಭಗವಂತನೇ ತೊಡಗಿ ಎಲ್ಲಾ ಕಾರ್ಯಗಳಲ್ಲೂ ಮುನ್ನೆಡೆಸುತ್ತಾನೆ]\nಎಂದು ತಿಳಿದವನು ಮತ್ತು ಏನು ಮಾಡುವುದಕ್ಕೂ ತಾನು ಸ್ವತಂತ್ರನಲ್ಲ[ಭಗವಂತನಿಗೆ ಇನ್ನೊಬ್ಬ ಕಾರಣ\nಪುರುಷನಿಲ್ಲ] ಎಂದು ತಿಳಿದವನು \"ನಿಜವಾಗಿ ತಿಳಿದವನು”.\n\nಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ಯಾರಿಗೆ “ನಾನು' ಮಾಡುತ್ತಿಲ್ಲ ಎಂದು ಗೊತ್ತಿದೆಯೋ ಅವನು ತಿಳಿದವನು” ಎಂದು.\nಆದ್ದರಿಂದ ಮೊದಲು ನಾವು “ನಾನು ಮಾಡುತ್ತಿದ್ದೇನೆ” ಎನ್ನು ವ ಅಹಂಕಾರವನ್ನು ಬಿಟ್ಟುಬಿಡಬೇಕು. ನಾನು\nಮಾಡುತ್ತಿದ್ದೇನೆ. ಎನ್ನುವುದು ಕೇವಲ ವ್ಯಾವಹಾರಿಕ ಸತ್ಯವೇ ಹೊರತು ಪಾರಮಾರ್ಥಿಕ ಸತ್ಯವಲ್ಲ.\nಉದಾಹರಣೆಗೆ: “ನಾನು ಮಾತನಾಡುತ್ತಿದ್ದೇನೆ”. ಇಲ್ಲಿ ನಾನು ಮಾತನಾಡಬೇಕಾದರೆ ಮೊದಲು ನಾನು\nಮೂಗನಾಗಿರಬಾರದು. . ಅದಕ್ಕೆ. ಸರಿಯಾದ ಅಂಗಾಂಗವಿರುವ ಮಾನವ ಶರೀರವಿರಬೇಕು.\nಮಾತನಾಡಬೇಕಾದರೆ ನನ್ನ ಮನಸ್ಸು ವಿಷಯಗಳನ್ನು ಸಮಯಕ್ಕೆ ಸರಿಯಾಗಿ ಯೋಚಿಸಿ ಸಂದೇಶವನ್ನು\nರವಾನಿಸಬೇಕು. ಅಂದರೆ ಇದಕ್ಕೆ ಸರಿಯಾದ ಮೆದುಳಿನ ಶಕ್ತಿ ನನಗೆ ಬೇಕು. ಮಾತನಾಡುವ ಧೈರ್ಯ ನನಗೆ\nಬೇಕು. ಈಗ ನಮಗೆ ನಾವೇ ಪ್ರಶ್ನೆ ಹಾಕಿಕೊಳ್ಳೋಣ: ನನಗೆ ಮಾತನಾಡಬಲ್ಲ ಮಾನವ ದೇಹವನ್ನು\nಕೊಟ್ಟವನ್ಯಾರು? ನನಗೆ ಯೋಚಿಸಬಲ್ಲ ಮೆದುಳನ್ನು ವಿನ್ಯಾಸಗೊಳಿಸಿ ಕರುಣಿಸಿದವನ್ಯಾರು? ಸಮಯಕ್ಕೆ\nಸರಿಯಾಗಿ ಈ ಮೆದುಳಿನಿಂದ ಸಂದೇಶವನ್ನು ರವಾನಿಸಿದವನ್ಯಾರು? ಮಾತನಾಡುವ ಅದ್ಭುತ ಕಲೆಯನ್ನು\nನನಗೆ ದಯಪಾಲಿಸಿದವನ್ಯಾರು? ಈ ಎಲ್ಲಾ ಪ್ರಶ್ನೆಯಿಂದ ನಮಗೆ ತಿಳಿಯುವುದೇನೆಂದರೆ: “ನನ್ನೊಳಗಿರುವ\nಭಗವಂತ ನುಡಿಸಿದ-ನಾನು ನುಡಿದೆ” ಎನ್ನುವ ಸತ್ಯ. ಇದನ್ನೇ ಇಲ್ಲಿ ಭಗವಂತ ವಿವರಿಸುತ್ತಾ ಹೇಳುತ್ತಾನೆ\n“ಪ್ರಕೃತ್ಯೆವ ಚ ಕರ್ಮಾಣಿ ಕ್ರಿಯಮಾಣಾನಿ ಸರ್ವಶಃ” ಎಂದು. ಅವರವರ ಜೀವಪ್ರಕೃತಿ(ಜೀವ ಸ್ವಭಾವ)ಗೆ\nಅನುಗುಣವಾಗಿ, ಪ್ರಕೃತಿ(ತ್ರಿಗುಣಗಳ) ಪ್ರಭಾವದಿಂದ, ಪ್ರಕೃತಿಪುರುಷರು(ಲಕ್ಷ್ಮೀನಾರಾಯಣರು) ನಮ್ಮಿಂದ\nಕರ್ಮವನ್ನು ಮಾಡಿಸುತ್ತಾರೆ. ಆದ್ದರಿಂದ ಜೀವನಿಗೆ ಅನಾಧಿನಿತ್ಯವಾಗಿ ಬಂದ ಜೀವಸ್ವಭಾವಕ್ಕನುಗುಣವಾಗಿ\nಆತನ ದೇಹ ಸೃಷ್ಟಿ ; ಅದಕ್ಕನುಗುಣವಾಗಿ ಆತನ ಮೇಲೆ ವಾತಾವರಣದಲ್ಲಿನ ತ್ರಿಗುಣಗಳ ಪ್ರಭಾವ; ತ್ರಿಗುಣಗಳ\nಪ್ರಭಾವದಂತೆ ಆತನ ಎಲ್ಲಾ ವಿಧದ ಕರ್ಮ. ಇದೆಲ್ಲವನ್ನೂ ಮಾಡಿಸುವವ- ಸರ್ವದೇವತೆಗಳ ಅಧಿಪತಿಯಾದ,\n\nಲಕ್ಷ್ಮೀ ಸಮೇತನಾದ ನಾರಾಯಣ.\n\nಯದಾ ಭೂತಪೃಥಗ್‌ ಭಾವಮೇಕಸ್ಥಮನುಪಶ್ಯತಿ ।\nತತ ಏವ ಚ ವಿಸ್ತಾರಂ ಬ್ರಹ್ಮ ಸಂಪದ್ಯತೇ ತದಾ 1೩೦॥\n\nಯದಾ ಭೂತ ಪೃಥಕ್‌ ಭಾವಮ್‌ ಏಕಸ್ಗಮ್‌ ಅನುಪಶ್ಯತಿ ।\nತತಃ ಏವ ಚ ವಿಸ್ತಾರಂ ಬ್ರಹ್ಮ ಸಂಪದ್ಯತೇ ತದಾ -ಬಗೆಬಗೆಯ ಜೀವರಾಶಿ ಒಬ್ಬ ಭಗವಂತನಲ್ಲಿ ನೆಲೆಸಿದೆ\nಎಂದು, ಅವನಿಂದಲೇ ಈ ಬಗೆಬಗೆಯ ಬಿತ್ತರ ಎಂದು ತಿಳಿದಾಗ ಭಗವಂತನನ್ನೇ ಸೇರುತ್ತಾನೆ.\n\nಜೀವ ಅನಾಧಿನಿತ್ಯ. ಸೃಷ್ಟಿ ಯಾಗುವುದು, ಸಂಹಾರವಾಗುವುದು ಕೇವಲ ಕಾಣುವ ರೂಪ ಅಷ್ಟೆ . ಜೀವಜಾತಗಳು\nಒಂದೊಂದೂ ಪೃಥಕ್‌ ಭಾವ. ಯಾವ ಎರಡು ಜೀವಜಾತವೂ ನೂರಕ್ಕೆ ನೂರು ಸದೃಶವಾಗಿಲ್ಲ. ಈ ಅನೇಕ\nಜೀವ ಸಮುದಾಯ ಏಕನಾದ ಭಗವಂತನಲ್ಲಿದೆ. ಸೃಷ್ಟಿ ಕಾಲದಲ್ಲಿ ಭಗವಂತನ ಉದರದಿಂದ ಹೊರ ಬಂದು\nಆಕಾರ ಪಡೆಯುವ ಜೀವ ಜಾತಗಳು ಪ್ರಳಯ ಕಾಲದಲ್ಲಿ ಮರಳಿ ಸೂಕ್ಷ್ಮ ರೂಪದಲ್ಲಿ ಭಗವಂತನ ಉದರವನ್ನು\nಸೇರುತ್ತವೆ. ಇದನ್ನು ನಾವು ವಸ್ತುಃಸ್ಥಿತಿಗೆ ಅನುಗುಣವಾಗಿ ಗ್ರಹಣ ಮಾಡಬೇಕು. ಯಾರು ಈ ಸತ್ಯವನ್ನು ಗ್ರಹಣ\nಮಾಡಬಲ್ಲನೋ ಆತ ಮೋಕ್ಷವನ್ನು ಪಡೆಯಬಲ್ಲ.\n\nಅನಾದಿತ್ವಾನ್ನಿರ್ಗುಣತ್ವಾತ್‌ ಪರಮಾತ್ಮಾಕಯಮವ್ಯಯಃ ।\n\nಶರೀರಸ್ಥೋ*",
  "13.30": "ಪ್ರಕೃತ್ಯಾ ಏವ ಚ ಕರ್ಮಾಣಿ ಕ್ರಿಯಮಾಣಾನಿ ಸರ್ವಶಃ |\n\nಯಃ ಪಶ್ಯತಿ ತಥಾ ಆತ್ಮಾನಮ್‌ ಅಕರ್ತಾರಮ್‌ ಸಃ ಪಶ್ಯತಿ -- ಪ್ರಕೃತಿಯಿಂದಲೇ ಎಲ್ಲಾ ಕಾರ್ಯಗಳೂ\nನಡೆಯುತ್ತಿವೆ[ಜೀವನ ಕರ್ಮಕ್ಕನುಗುಣವಾಗಿ ಭಗವಂತನೇ ತೊಡಗಿ ಎಲ್ಲಾ ಕಾರ್ಯಗಳಲ್ಲೂ ಮುನ್ನೆಡೆಸುತ್ತಾನೆ]\nಎಂದು ತಿಳಿದವನು ಮತ್ತು ಏನು ಮಾಡುವುದಕ್ಕೂ ತಾನು ಸ್ವತಂತ್ರನಲ್ಲ[ಭಗವಂತನಿಗೆ ಇನ್ನೊಬ್ಬ ಕಾರಣ\nಪುರುಷನಿಲ್ಲ] ಎಂದು ತಿಳಿದವನು \"ನಿಜವಾಗಿ ತಿಳಿದವನು”.\n\nಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ಯಾರಿಗೆ “ನಾನು' ಮಾಡುತ್ತಿಲ್ಲ ಎಂದು ಗೊತ್ತಿದೆಯೋ ಅವನು ತಿಳಿದವನು” ಎಂದು.\nಆದ್ದರಿಂದ ಮೊದಲು ನಾವು “ನಾನು ಮಾಡುತ್ತಿದ್ದೇನೆ” ಎನ್ನು ವ ಅಹಂಕಾರವನ್ನು ಬಿಟ್ಟುಬಿಡಬೇಕು. ನಾನು\nಮಾಡುತ್ತಿದ್ದೇನೆ. ಎನ್ನುವುದು ಕೇವಲ ವ್ಯಾವಹಾರಿಕ ಸತ್ಯವೇ ಹೊರತು ಪಾರಮಾರ್ಥಿಕ ಸತ್ಯವಲ್ಲ.\nಉದಾಹರಣೆಗೆ: “ನಾನು ಮಾತನಾಡುತ್ತಿದ್ದೇನೆ”. ಇಲ್ಲಿ ನಾನು ಮಾತನಾಡಬೇಕಾದರೆ ಮೊದಲು ನಾನು\nಮೂಗನಾಗಿರಬಾರದು. . ಅದಕ್ಕೆ. ಸರಿಯಾದ ಅಂಗಾಂಗವಿರುವ ಮಾನವ ಶರೀರವಿರಬೇಕು.\nಮಾತನಾಡಬೇಕಾದರೆ ನನ್ನ ಮನಸ್ಸು ವಿಷಯಗಳನ್ನು ಸಮಯಕ್ಕೆ ಸರಿಯಾಗಿ ಯೋಚಿಸಿ ಸಂದೇಶವನ್ನು\nರವಾನಿಸಬೇಕು. ಅಂದರೆ ಇದಕ್ಕೆ ಸರಿಯಾದ ಮೆದುಳಿನ ಶಕ್ತಿ ನನಗೆ ಬೇಕು. ಮಾತನಾಡುವ ಧೈರ್ಯ ನನಗೆ\nಬೇಕು. ಈಗ ನಮಗೆ ನಾವೇ ಪ್ರಶ್ನೆ ಹಾಕಿಕೊಳ್ಳೋಣ: ನನಗೆ ಮಾತನಾಡಬಲ್ಲ ಮಾನವ ದೇಹವನ್ನು\nಕೊಟ್ಟವನ್ಯಾರು? ನನಗೆ ಯೋಚಿಸಬಲ್ಲ ಮೆದುಳನ್ನು ವಿನ್ಯಾಸಗೊಳಿಸಿ ಕರುಣಿಸಿದವನ್ಯಾರು? ಸಮಯಕ್ಕೆ\nಸರಿಯಾಗಿ ಈ ಮೆದುಳಿನಿಂದ ಸಂದೇಶವನ್ನು ರವಾನಿಸಿದವನ್ಯಾರು? ಮಾತನಾಡುವ ಅದ್ಭುತ ಕಲೆಯನ್ನು\nನನಗೆ ದಯಪಾಲಿಸಿದವನ್ಯಾರು? ಈ ಎಲ್ಲಾ ಪ್ರಶ್ನೆಯಿಂದ ನಮಗೆ ತಿಳಿಯುವುದೇನೆಂದರೆ: “ನನ್ನೊಳಗಿರುವ\nಭಗವಂತ ನುಡಿಸಿದ-ನಾನು ನುಡಿದೆ” ಎನ್ನುವ ಸತ್ಯ. ಇದನ್ನೇ ಇಲ್ಲಿ ಭಗವಂತ ವಿವರಿಸುತ್ತಾ ಹೇಳುತ್ತಾನೆ\n“ಪ್ರಕೃತ್ಯೆವ ಚ ಕರ್ಮಾಣಿ ಕ್ರಿಯಮಾಣಾನಿ ಸರ್ವಶಃ” ಎಂದು. ಅವರವರ ಜೀವಪ್ರಕೃತಿ(ಜೀವ ಸ್ವಭಾವ)ಗೆ\nಅನುಗುಣವಾಗಿ, ಪ್ರಕೃತಿ(ತ್ರಿಗುಣಗಳ) ಪ್ರಭಾವದಿಂದ, ಪ್ರಕೃತಿಪುರುಷರು(ಲಕ್ಷ್ಮೀನಾರಾಯಣರು) ನಮ್ಮಿಂದ\nಕರ್ಮವನ್ನು ಮಾಡಿಸುತ್ತಾರೆ. ಆದ್ದರಿಂದ ಜೀವನಿಗೆ ಅನಾಧಿನಿತ್ಯವಾಗಿ ಬಂದ ಜೀವಸ್ವಭಾವಕ್ಕನುಗುಣವಾಗಿ\nಆತನ ದೇಹ ಸೃಷ್ಟಿ ; ಅದಕ್ಕನುಗುಣವಾಗಿ ಆತನ ಮೇಲೆ ವಾತಾವರಣದಲ್ಲಿನ ತ್ರಿಗುಣಗಳ ಪ್ರಭಾವ; ತ್ರಿಗುಣಗಳ\nಪ್ರಭಾವದಂತೆ ಆತನ ಎಲ್ಲಾ ವಿಧದ ಕರ್ಮ. ಇದೆಲ್ಲವನ್ನೂ ಮಾಡಿಸುವವ- ಸರ್ವದೇವತೆಗಳ ಅಧಿಪತಿಯಾದ,\n\nಲಕ್ಷ್ಮೀ ಸಮೇತನಾದ ನಾರಾಯಣ.\n\nಯದಾ ಭೂತ ಪೃಥಕ್‌ ಭಾವಮ್‌ ಏಕಸ್ಗಮ್‌ ಅನುಪಶ್ಯತಿ ।\nತತಃ ಏವ ಚ ವಿಸ್ತಾರಂ ಬ್ರಹ್ಮ ಸಂಪದ್ಯತೇ ತದಾ -ಬಗೆಬಗೆಯ ಜೀವರಾಶಿ ಒಬ್ಬ ಭಗವಂತನಲ್ಲಿ ನೆಲೆಸಿದೆ\nಎಂದು, ಅವನಿಂದಲೇ ಈ ಬಗೆಬಗೆಯ ಬಿತ್ತರ ಎಂದು ತಿಳಿದಾಗ ಭಗವಂತನನ್ನೇ ಸೇರುತ್ತಾನೆ.\n\nಜೀವ ಅನಾಧಿನಿತ್ಯ. ಸೃಷ್ಟಿ ಯಾಗುವುದು, ಸಂಹಾರವಾಗುವುದು ಕೇವಲ ಕಾಣುವ ರೂಪ ಅಷ್ಟೆ . ಜೀವಜಾತಗಳು\nಒಂದೊಂದೂ ಪೃಥಕ್‌ ಭಾವ. ಯಾವ ಎರಡು ಜೀವಜಾತವೂ ನೂರಕ್ಕೆ ನೂರು ಸದೃಶವಾಗಿಲ್ಲ. ಈ ಅನೇಕ\nಜೀವ ಸಮುದಾಯ ಏಕನಾದ ಭಗವಂತನಲ್ಲಿದೆ. ಸೃಷ್ಟಿ ಕಾಲದಲ್ಲಿ ಭಗವಂತನ ಉದರದಿಂದ ಹೊರ ಬಂದು\nಆಕಾರ ಪಡೆಯುವ ಜೀವ ಜಾತಗಳು ಪ್ರಳಯ ಕಾಲದಲ್ಲಿ ಮರಳಿ ಸೂಕ್ಷ್ಮ ರೂಪದಲ್ಲಿ ಭಗವಂತನ ಉದರವನ್ನು\nಸೇರುತ್ತವೆ. ಇದನ್ನು ನಾವು ವಸ್ತುಃಸ್ಥಿತಿಗೆ ಅನುಗುಣವಾಗಿ ಗ್ರಹಣ ಮಾಡಬೇಕು. ಯಾರು ಈ ಸತ್ಯವನ್ನು ಗ್ರಹಣ\nಮಾಡಬಲ್ಲನೋ ಆತ ಮೋಕ್ಷವನ್ನು ಪಡೆಯಬಲ್ಲ.\n",
  "13.31": "ಅನಾದಿತ್ವಾತ್‌ ನಿರ್ಗುಣತ್ವಾತ್‌ ಪರಮ ಆತ್ಮಾ ಅಯಮ್‌ ಅವ್ಯಯಃ ।\n\nಶರೀರಸ್ಥಃ ಅಪಿ ಕೌಂತೇಯ ನ ಕರೋತಿ ನ ಲಿಪ್ಯತೇ --ಕೌಂತೇಯಾ, ಪರಮಾತ್ಮ ಎಂದೂ ಹುಟ್ಟದವನು;\nಗುಣಗಳು ಅಂಟದವನು; ಅದರಿಂದ ಅವನಿಗೆ ಅಳಿವೂ ಇಲ್ಲ. ಅವನು ದೇಹದೊಳಗಿದ್ದೂ ಏನನ್ನೂ\nಮಾಡುವುದಿಲ್ಲ; ಏನನ್ನೂ ಅಂಟಿಸಿಕೊಳ್ಳುವುದಿಲ್ಲ.[ಅಳಿವಿರದ ಈ ಪರಮಾತ್ಮ ಸಂಸಾರಿ ಜೀವನಲ್ಲ; ಜಡದ\nಮಾತೇನು! ಅವನು ಎಲ್ಲವನ್ನೂ ಮಾಡುತ್ತಾನೆ; ಏನನ್ನೂ ಅಂಟಿಸಿಕೊಳ್ಳುವುದಿಲ್ಲ.]\n\nನಿರ್ವಿಕಾರನಾಗಿರುವ ಏಕಮೇವ ವಸ್ತು ಎಂದರೆ ಭಗವಂತ. ಆತ ಎಂದೂ ಯಾವ ಕಾರಣ ವಿಶೇಷದಿಂದ ಕೂಡಾ\nಹುಟ್ಟಿಲ್ಲ. ಭಗವಂತ ತ್ರೈಗುಣ್ಯವರ್ಜಿತ. ಇದರಿಂದ ಆತ ಎಂದೂ ಬದಲಾವಣೆಗೆ, ವಿಕಾರಕ್ಕೆ ಒಳಪಡುವುದಿಲ್ಲ. ಆತ\nಎಲ್ಲಾ ಜೀವರೊಳಗೆ ಬಿಂಬರೂಪನಾಗಿದ್ದರೂ ಕೂಡಾ ಆತನಿಗೆ ದೇಹದ ಬದ್ಧತೆ ಇಲ್ಲ. ಆತ ಎಲ್ಲವನ್ನು ನಮ್ಮಿಂದ\nಮಾಡಿಸುತ್ತಾನೆ ಆದರೆ ಏನನ್ನೂ ಅಂಟಿಸಿಕೊಳ್ಳುವುದಿಲ್ಲ. ಆತ ನಿರ್ಲಿಪ್ತನಾಗಿ ಎಲ್ಲವನ್ನೂ ಮಾಡುತ್ತಾನೆ ಆದರೆ\nಯಾವುದರ ಲೇಪವೂ ಆತನಿಗಿಲ್ಲ. ಇದು ಯಾವ ರೀತಿ ಎಂದು ಅರ್ಥ ಮಾಡಿಕೊಳ್ಳುವುದಕ್ಕೆ- ಕೃಷ್ಣ ಒಂದು\nಉದಾಹರಣೆಯನ್ನು ಕೊಟ್ಟು ಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ವಿವರಿಸುತ್ತಾನೆ.\n\nಯಥಾ ಸರ್ವಗತಂ ಸೌಕ್ಷ್ಮಾದಾಕಾಶಂ ನೋಪಲಿಪ್ಯತೇ।\nಸರ್ವತ್ರಾವಸ್ಥಿತೋ ದೇಹೇ ತಥಾ$5ತ್ಮಾ ನೋಪಲಿಷ್ಯತೇ ॥೩೦೨॥\n\nಯಥಾ ಸರ್ವಗತಮ್‌ ಸೌಕ್ಷ್ಮಾತ್‌ ಆಕಾಶಮ್‌ ನ ಉಪಲಿಪ್ಯತೇ |\n\nಸರ್ವತ್ರ ಅವಸ್ಥಿತಃ ದೇಹೇ ತಥಾ ಆತ್ಮಾ ನ ಉಪಲಿಪ್ಯತೇ -ಆಕಾಶ ಎಲ್ಲೆಡೆ ತುಂಬಿದ್ದರೂ ಏತಕ್ಕೂ\nತಡೆಯಾಗದಷ್ಟು ನವುರಾದ್ದರಿಂದ ಏತರಿಂದಲೂ ಅಂಟಿಸಿಕೊಳ್ಳುವುದಿಲ್ಲ ಹೇಗೋ ಹಾಗೇ- ಪರಮಾತ್ಮ ಕೂಡಾ\nಎಲ್ಲಾ ದೇಹಗಳಲ್ಲಿ ತುಂಬಿದ್ದರೂ ಅಂಟಿಕೊಳ್ಳುವುದಿಲ್ಲ.\n\nಎಲ್ಲಾ ಕಡೆ ಆಕಾಶವಿದೆ. ಅದಿಲ್ಲದ ಸ್ಥಳವಿಲ್ಲ. ಇಂತಹ ಆಕಾಶ ಎಲ್ಲೆಡೆ ಇದ್ದೂ ಹೇಗೆ ಏನನ್ನೂ ಅಂಟಿಸಿಕೊಳ್ಳದೇ\nಇರುತ್ತದೋ- ಹಾಗೇ ಭಗವಂತ ಎಲ್ಲಾ ದೇಹದಲ್ಲಿದ್ದರೂ ಏನನ್ನೂ ಅಂಟಿಸಿಕೊಳ್ಳದೆ ನಿರ್ಲಿಪ್ತನಾಗಿದ್ದಾನೆ.\n\nಯಥಾ ಪ್ರಕಾಶಯತ್ಯೇಕಃ ಕೃತ್ಸ್ನಂ ಲೋಕಮಿ",
  "13.32": "ಶರೀರಸ್ಥಃ ಅಪಿ ಕೌಂತೇಯ ನ ಕರೋತಿ ನ ಲಿಪ್ಯತೇ --ಕೌಂತೇಯಾ, ಪರಮಾತ್ಮ ಎಂದೂ ಹುಟ್ಟದವನು;\nಗುಣಗಳು ಅಂಟದವನು; ಅದರಿಂದ ಅವನಿಗೆ ಅಳಿವೂ ಇಲ್ಲ. ಅವನು ದೇಹದೊಳಗಿದ್ದೂ ಏನನ್ನೂ\nಮಾಡುವುದಿಲ್ಲ; ಏನನ್ನೂ ಅಂಟಿಸಿಕೊಳ್ಳುವುದಿಲ್ಲ.[ಅಳಿವಿರದ ಈ ಪರಮಾತ್ಮ ಸಂಸಾರಿ ಜೀವನಲ್ಲ; ಜಡದ\nಮಾತೇನು! ಅವನು ಎಲ್ಲವನ್ನೂ ಮಾಡುತ್ತಾನೆ; ಏನನ್ನೂ ಅಂಟಿಸಿಕೊಳ್ಳುವುದಿಲ್ಲ.]\n\nನಿರ್ವಿಕಾರನಾಗಿರುವ ಏಕಮೇವ ವಸ್ತು ಎಂದರೆ ಭಗವಂತ. ಆತ ಎಂದೂ ಯಾವ ಕಾರಣ ವಿಶೇಷದಿಂದ ಕೂಡಾ\nಹುಟ್ಟಿಲ್ಲ. ಭಗವಂತ ತ್ರೈಗುಣ್ಯವರ್ಜಿತ. ಇದರಿಂದ ಆತ ಎಂದೂ ಬದಲಾವಣೆಗೆ, ವಿಕಾರಕ್ಕೆ ಒಳಪಡುವುದಿಲ್ಲ. ಆತ\nಎಲ್ಲಾ ಜೀವರೊಳಗೆ ಬಿಂಬರೂಪನಾಗಿದ್ದರೂ ಕೂಡಾ ಆತನಿಗೆ ದೇಹದ ಬದ್ಧತೆ ಇಲ್ಲ. ಆತ ಎಲ್ಲವನ್ನು ನಮ್ಮಿಂದ\nಮಾಡಿಸುತ್ತಾನೆ ಆದರೆ ಏನನ್ನೂ ಅಂಟಿಸಿಕೊಳ್ಳುವುದಿಲ್ಲ. ಆತ ನಿರ್ಲಿಪ್ತನಾಗಿ ಎಲ್ಲವನ್ನೂ ಮಾಡುತ್ತಾನೆ ಆದರೆ\nಯಾವುದರ ಲೇಪವೂ ಆತನಿಗಿಲ್ಲ. ಇದು ಯಾವ ರೀತಿ ಎಂದು ಅರ್ಥ ಮಾಡಿಕೊಳ್ಳುವುದಕ್ಕೆ- ಕೃಷ್ಣ ಒಂದು\nಉದಾಹರಣೆಯನ್ನು ಕೊಟ್ಟು ಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ವಿವರಿಸುತ್ತಾನೆ.\n\nಯಥಾ ಸರ್ವಗತಂ ಸೌಕ್ಷ್ಮಾದಾಕಾಶಂ ನೋಪಲಿಪ್ಯತೇ।\nಸರ್ವತ್ರಾವಸ್ಥಿತೋ ದೇಹೇ ತಥಾ$5ತ್ಮಾ ನೋಪಲಿಷ್ಯತೇ ॥೩೦೨॥\n\nಯಥಾ ಸರ್ವಗತಮ್‌ ಸೌಕ್ಷ್ಮಾತ್‌ ಆಕಾಶಮ್‌ ನ ಉಪಲಿಪ್ಯತೇ |\n\nಸರ್ವತ್ರ ಅವಸ್ಥಿತಃ ದೇಹೇ ತಥಾ ಆತ್ಮಾ ನ ಉಪಲಿಪ್ಯತೇ -ಆಕಾಶ ಎಲ್ಲೆಡೆ ತುಂಬಿದ್ದರೂ ಏತಕ್ಕೂ\nತಡೆಯಾಗದಷ್ಟು ನವುರಾದ್ದರಿಂದ ಏತರಿಂದಲೂ ಅಂಟಿಸಿಕೊಳ್ಳುವುದಿಲ್ಲ ಹೇಗೋ ಹಾಗೇ- ಪರಮಾತ್ಮ ಕೂಡಾ\nಎಲ್ಲಾ ದೇಹಗಳಲ್ಲಿ ತುಂಬಿದ್ದರೂ ಅಂಟಿಕೊಳ್ಳುವುದಿಲ್ಲ.\n\nಎಲ್ಲಾ ಕಡೆ ಆಕಾಶವಿದೆ. ಅದಿಲ್ಲದ ಸ್ಥಳವಿಲ್ಲ. ಇಂತಹ ಆಕಾಶ ಎಲ್ಲೆಡೆ ಇದ್ದೂ ಹೇಗೆ ಏನನ್ನೂ ಅಂಟಿಸಿಕೊಳ್ಳದೇ\nಇರುತ್ತದೋ- ಹಾಗೇ ಭಗವಂತ ಎಲ್ಲಾ ದೇಹದಲ್ಲಿದ್ದರೂ ಏನನ್ನೂ ಅಂಟಿಸಿಕೊಳ್ಳದೆ ನಿರ್ಲಿಪ್ತನಾಗಿದ್ದಾನೆ.\n\nಯಥಾ ಪ್ರಕಾಶಯತ್ಯೇಕಃ ಕೃತ್ಸ್ನಂ ಲೋಕಮಿ",
  "13.33": "ಯಥಾ ಪ್ರಕಾಶಯತಿ ಏಕಃ ಕೃತ್ಸ ಮ್‌ ಲೋಕಮ್‌ ಇಮಮ್‌ ರವಿಃ।\n\nಕ್ಷೇತ್ರಮ್‌ ಕ್ಷೇತ್ರೀ ತಥಾ ಕೃತ್ಸ್ನಮ್‌ ಪ್ರಕಾಶಯತಿ ಭಾರತ -ಭಾರತಾ, ಒಬ್ಬ ಸೂರ್ಯ ಇಡಿಯ ಈ\nಭೂಮಿಯನ್ನು ಬೆಳಗುವಂತೆ “ಕ್ಷೇತ್ರಜ್ಞ”ನಾದ ಭಗವಂತನೊಬ್ಬನೇ ಇಡಿಯ ವಿಶ್ವವೆಂಬ “ಕ್ಷೇತ್ರ” ವನ್ನು\nಬೆಳಗುತ್ತಾನೆ.\n\nಏಕ ಸೂರ್ಯ ಹೇಗೆ ಇಡೀ ವಿಶ್ವವನ್ನು ಬೆಳಗಿಸುತ್ತಾನೋ ಹಾಗೇ, ಇಡೀ ಕ್ಷೇತ್ರವನ್ನು ಕ್ಷೇತ್ರಜ್ಞನಾದ ಭಗವಂತ\nಬೆಳಗಿಸುತ್ತಾನೆ. ನಾವು ಮೊದಲು ಭಗವಂತನ ಬೆಳಕನ್ನು(ಜ್ಞಾನವನ್ನು) ತಿಳಿಯಬೇಕು. ಆಗ ನಮ್ಮೊಳಗಿನ ಬೆಳಕು\nನಮಗೆ ಅರ್ಥವಾಗುತ್ತದೆ.\n",
  "13.34": "ಕ್ಷೇತ್ರ ಕ್ಷೇತ್ರಜ್ಞಯೋಃ ಏವಮ್‌ ಅಂತರಮ್‌ ಜ್ಞಾನೊ ಚಕ್ಷುಷಾ ।\n\nಭೂತ ಪ್ರಕೃತಿ ಮೋಕ್ಷಮ್‌ ಚ ಯೇ ವಿದುಃ ಯಾಂತಿ ತೇ ಪರಮ್‌ - ಕ್ಷೇತ್ರ-ಕ್ಷೇತ್ರಜ್ಞರೊಳಗಣ ಈ ಅಂತರವನ್ನು,\nಪಂಚಭೂತಗಳಿಂದ ಮತ್ತು ಪ್ರಕೃತಿಯಿಂದ [ಜೀವರಿಗೆ ಚೇತನ ಪ್ರಕೃತಿಯಿಂದ] ಬಿಡುಗಡೆಗೆ ಕಾರಣವಾದ\nತಿಳಿವಿನ ದಾರಿಯನ್ನು ತುಳಿದವರು ಪರಮಾತ್ಮನನ್ನು ಪಡೆಯುತ್ತಾರೆ.\n\nಈ ಶ್ಲೋಕ ಈ ಅಧ್ಯಾಯದ ಉಪಸಂಹಾರ. ಕ್ಷೇತ್ರ ಅಂದರೇನು, ಕ್ಷೇತ್ರಜ್ಞ ಅಂದರೇನು, ಕ್ಷೇತ್ರ ಮತ್ತು ಕ್ಷೇತ್ರಜ್ಞರ\nನಡುವಿನ ವ್ಯತ್ಯಾಸವೇನು; ಜೀವಜಾತ ಜಡದಿಂದ ಬಿಡುಗಡೆ ಹೊಂದಲು ಇರಬೇಕಾದ ಮೋಕ್ಷ ಸಾಧಕ\nಗುಣಗಳು-ಇವೆಲ್ಲವನ್ನು ಅರಿತು ಆಚರಣೆಗೆ ತಂದು ಬದುಕುವವರು ಸರ್ವಶ್ರೇಷ್ಠನಾದ ಭಗವಂತನನ್ನು\nಸೇರುತ್ತಾರೆ.\nಇತಿ ತ್ರಯೋದಶೋ*ಧ್ಯಾಯಃ\nಹದಿಮೂರನೆಯಯ ಅಧ್ಯಾಯ ಮುಗಿಯಿತು\n\nಅಧ್ಯಾಯ ಹದಿನಾಲ್ಕು\n\nಗೀತೆಯಲ್ಲಿ ಇಲ್ಲಿಯ ತನಕ ಅಲ್ಲಲ್ಲಿ ಸಾಧನೆಯ ಮಾತು ಬಂದಿದ್ದರೂ ಕೂಡಾ, ಭಗವಂತನ ಸ್ವರೂಪದ\nಮಹಿಮೆಯ ಮಾತು ಹೆಚ್ಚಾಗಿ ಬಂದಿದೆ. ಇಂತಹ ಭಗವಂತನ ಉಪಾಸನೆಯ ಮುಖಗಳ ವರ್ಣನೆಯನ್ನು ನಾವು\nಇನ್ನು ಮುಂದೆ ಕಾಣಬಹುದು. ಹನ್ನೆರಡನೇ ಅಧ್ಯಾಯದಲ್ಲಿ(ಶ್ಲೋ-೦೫) ಕೃಷ್ಣ \"ಶ್ರೀತತ್ವದ ಉಪಾಸನೆ ತುಂಬಾ\nಕಷ್ಟ, ಇದು ನೇರ ದಾರಿಯನ್ನು ಬಿಟ್ಟು ಬಳಸುದಾರಿಯಲ್ಲಿ ಭಗವಂತನೆಡೆಗೆ ಪಯಣಿಸಿದಂತೆ, ಸಾಧಕರು ಇದನ್ನು\nಬಹಳ ಕಷ್ಟದಿಂದ ಸಾಧಿಸಬೇಕು”-ಎನ್ನುವ ಎಚ್ಚರವನ್ನು ಕೊಟ್ಟ. ಹದಿಮೂರನೇ ಅಧ್ಯಾಯದಲ್ಲಿ(ಶ್ಲೋ-೨೬)-\n\"ಸಿರ ಮತ್ತು ಚರ ಜೀವಿಗಳಲ್ಲಿ ಯಾವುದು ಹುಟ್ಟಿದರೂ ಅದು ಕ್ಷೇತ್ರ[ಶ್ರೀತತ್ವ] ಮತ್ತು ಕ್ಷೇತ್ರಜ್ಞ[ಭಗವಂತ]ರ\nಸಂಯೋಗದಿಂದಲೇ”-ಎಂದು ಹೇಳಿದ. ಸಾಮಾನ್ಯವಾಗಿ ಸೃಷ್ಟಿಯ ಮಾತು ಬಂದಾಗ ಭಗವಂತ ಸೃಷ್ಟಿ\nಮಾಡಿದ' ಎನ್ನುತ್ತೇವೆ. ಇಲ್ಲಿ ಎಲ್ಲಿಯೂ ಲಕ್ಷ್ಮಿಯ ಮಾತು ಬರುವುದಿಲ್ಲ. ಆದರೆ ಹಿಂದಿನ ಅಧ್ಯಾಯದಲ್ಲಿ ಕೃಷ್ಣ\nಸ್ಪಷ್ಟವಾಗಿ ಹೇಳಿದ: “ಈ ಸೃಷ್ಟಿ ಲಕ್ಷ್ಮೀನಾರಾಯಣರ ದಾಂಪತ್ಯದ ಫಲ” ಎಂದು. ಈ ಕಾರಣದಿಂದ ಸೃಷ್ಟಿ\nಮೂಲದ ಚಿಂತನೆಯಲ್ಲಿ ಲಕ್ಷ್ಮೀನಾರಾಯಣರನ್ನು ಒಟ್ಟಿಗೆ ಸ್ತುತಿಸುವುದು ಶ್ರೇಷ್ಠ. ಲಕ್ಷ್ಮಿಯನ್ನು ಸ್ತುತಿಸುವಾಗ\nಜೊತೆಗೆ ನಾರಾಯಣನನ್ನು ಸ್ತುತಿಸಿ ಲಕ್ಷ್ಮಿಯ ಸ್ತೋತ್ರ ಮಾಡಬೇಕು ಎನ್ನುವುದನ್ನು ಆಚಾರ್ಯರು ದ್ವಾದಶ\nಸ್ತೋತ್ರದಲ್ಲಿ ಸ್ಪಷ್ಟವಾಗಿ ತೋರಿಸಿದ್ದಾರೆ. ಅಲ್ಲಿ 'ಶ್ರೀಸ್ಪುತಿ' ಎನ್ನುವ ಲಕ್ಷ್ಮೀದೇವಿಯ ಸ್ತುತಿ ಈ ರೀತಿ ಹೇಳುತ್ತದೆ:\nವಿಶ್ವಸ್ಥಿತಿಪ್ರಥಳಯಸರ್ಗಮಹಾವಿಭೂತಿ ವೃತ್ತಿಪ್ರಕಾಶನಿಯಮಾವೃತಿ ಬಂಧಮೋಕ್ಷಾಃ |\nಯಸ್ಯಾ ಅಪಾಂಗಲವಮಾತ್ರತ ಉಊರ್ಜಿತಾ ಸಾ ಶ್ರೀಃ ಯತ್ಕಟಾಕ್ಷಬಲವತ್ಯಜಿತಂ ನಮಾಮಿ ॥ ೧॥\n\nಅಂದರೆ “ಯಾರ ಕಟಾಕ್ಷದ ಬಲದಿಂದ ಇಡಿಯ ಸೃಷ್ಟಿ-ಸ್ಥಿತಿ-ಸಂಹಾರವನ್ನು ಲಕ್ಷ್ಮಿ ಮಾಡುತ್ತಾಳೋ, ಅಂತಹ\nಲಕ್ಷ್ಮಿಯ ಪತಿಯಾದ ನಾರಾಯಣನಿಗೆ ನಮಸ್ಕಾರ” ಎಂದು. ಇಲ್ಲಿ ಲಕ್ಷ್ಮಿಯನ್ನು ಒಂದು ಸ್ತೋತ್ರದಲ್ಲಿ ಪೂರ್ಣ\nವರ್ಣನೆ ಮಾಡಿ, ಅಂತಹ ಲಕ್ಷ್ಮಿಯ ಪತಿಯಾದ ನಾರಾಯಣನಿಗೆ ನಮಸ್ಕಾರ ಎಂದು ಹೇಳಿದ್ದಾರೆ. ಆದ್ದರಿಂದ\nಲಕ್ಷ್ಮೀನಾರಾಯಣರ ಸ್ತುತಿಯೇ ಲಕ್ಷ್ಮಿಸ್ತುತಿ, ಹೊರತು ಕೇವಲ ಲಕ್ಷ್ಮಿ ಸ್ತುತಿ ಅಲ್ಲ. ಇದಕ್ಕೆ ಮೂಲ-ಗೀತೆಯ\nಹನ್ನೆ ರಡು, ಹದಿಮೂರು ಮತ್ತು ಹದಿನಾಲ್ಕನೇ ಅಧ್ಯಾಯ. ಹನ್ನೆ ರಡನೇ ಅಧ್ಯಾಯದಲ್ಲಿ ಕೇವಲ ಲಕ್ಷ್ಮಿ ಉಪಾಸನೆ\nಮಾಡಿದರೆ ಖಂಡಿತವಾಗಿ ಆಕೆ ಒಲಿಯಳು ಎನ್ನುವ ಎಚ್ಚರವಿದ್ದರೆ, ಹದಿಮೂರನೇ ಅಧ್ಯಾಯದಲ್ಲಿ ಈ ಜಗತ್ತು\nಲಕ್ಷ್ಮೀನಾರಾಯಣರ ಸಂಯೋಗದಿಂದ ರಚನೆಯಾಯಿತು- ಆದ್ದರಿಂದ ನಾವೆಲ್ಲರೂ ಅವರ ಮಕ್ಕಳು ಎನ್ನುವ\nಸಂದೇಶವಿದೆ. ಭಗವಂತನ ಜೊತೆಗೆ ಸೃಷ್ಟಿ ಪ್ರಕ್ರಿಯೆಯಲ್ಲಿ ಲಕ್ಷ್ಮಿಯ ಅನುಸಂಧಾನ ಹೇಗೆ ಅನ್ನುವುದನ್ನು\nಹದಿನಾಲ್ಕನೇ ಅಧ್ಯಾಯ ವಿವರಿಸುತ್ತದೆ. ಲಕ್ಷ್ಮಿ, ಶ್ರೀ.ಭೂ-ದುರ್ಗ ಈ ಮೂರು ರೂಪದಲ್ಲಿ ಸತ್ವ-ರಜಸ್ಸು-\nತಮೋಗುಣಗಳ ನಿಯಾಮಕ ಶಕ್ತಿಯಾದ್ದರಿಂದ-ಅವಳ ಮಕ್ಕಳು ಸಾತ್ವಿಕರು-ರಾಜಸರು-ತಾಮಸರು ಎನ್ನುವ\nಮೂರು ಬಗೆ. ಈ ವಿಚಾರವನ್ನು ಮೊತ್ತಮೊದಲ ಬಾರಿ ಈ ಅಧ್ಯಾಯದಲ್ಲಿ ಹೇಳಲಾಗಿದೆ. ಹಿಂದಿನ ಯಾವ\nಅಧ್ಯಾಯದಲ್ಲೂ ಕೂಡಾ ತ್ರೈವಿದ್ಯರ ವಿವರ ಇಷ್ಟು ಸ್ಟ ಷ್ಟ ವಾಗಿ ಬಂದಿಲ್ಲ. ನಾವು ಈ ತ್ರಿಗುಣಗಳ ವಿಶ್ಲೇಷಣೆ\nಮಾಡಿ, ನಮ್ಮಲ್ಲಿರುವ ರಾಜಸ ಮತ್ತು ತಾಮಸ ಅಂಶವನ್ನು ತಿದ್ದಿಕೊಂಡು, ಹೇಗೆ ಸಾತ್ವಿಕ ದಾರಿಯಲ್ಲಿ\nಸಾಧನೆಯನ್ನು ಮಾಡಬಹುದು ಎನ್ನುವ ಅಂಶವನ್ನು ಈ ಅಧ್ಯಾಯದಲ್ಲಿ ಕಾಣಬಹುದು.\n\nಭಗವಾನುವಾಚ ।\nಪರಂ ಭೂಯಃ ಪ್ರವಕ್ಷ್ಯಾಮಿ ಜ್ಞಾನಾನಾಂ ಜ್ಞಾನಮುತ್ತಮಮ್‌ |।\nಯಜ್‌ ಜ್ಞಾತ್ವಾ ಮುನಯಃ ಸರ್ವೇ ಪರಾಂ ಸಿದ್ಧಿಮಿತೋ ಗತಾಃ॥೧॥\n\nಭಗವಾನ್‌ ಉವಾಚ-ಭಗವಂತ ಹೇಳಿದನು:\n\nಪರಮ್‌ ಭೂಯಃ ಪ್ರವಕ್ಷ್ಯಾಮಿ ಜ್ಞಾನಾನಾಮ್‌ ಜ್ಞಾನಮ್‌ ಉತ್ತಮಮ್‌ |\n\nಯತ್‌ ಜ್ಞಾತ್ವಾ ಮುನಯಃ ಸರ್ವೇ ಪರಾಮ್‌ ಸಿದ್ಧಿಮ್‌ ಇತಃ ಗತಾಃ -ತಿಳಿಯಬೇಕಾದ ಸಂಗತಿಗಳಲ್ಲಿ ಹಿರಿದಾದ\nತಿಳಿವನ್ನು ಇನ್ನಷ್ಟು ಹೇಳುತ್ತೇನೆ; ಎಲ್ಲಾ ಮುನಿಗಳು ಇದನ್ನರಿತು ಇಲ್ಲಿಂದ ಪರಮಪದವನ್ನೈದಿದರು.\n\nಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಇನ್ನೂ ಹೇಳುತ್ತೇನೆ” ಎಂದು. ಇದು ಬಹಳ ಮುಖ್ಯವಾದ ಮಾತು. ಸಾಮಾನ್ಯವಾಗಿ ಶಿಷ್ಯರು\nಒತ್ತಾಯ ಮಾಡಿದರೂ ಗುರುಗಳು ಹೇಳುವುದಿಲ್ಲ. ಗುರುಗಳಿಗೆ ಶಿಷ್ಯನ ಜ್ಞಾನ ತೃಷೆಯನ್ನು ಕಂಡು ಹೇಳಬೇಕು\nಅನ್ನಿಸಬೇಕು ಮತ್ತು ಅವರು ಖುಷಿಯಿಂದ ಹೇಳಬೇಕು. ಆಗ ಶಿಷ್ಯನಿಗೆ ಆ ವಿದ್ಯೆ ಫಲಿಸುತ್ತದೆ. ಹೀಗೆ ಜ್ಞಾನ\nತೃಷೆಯನ್ನು ಕಂಡು ಖುಷಿಯಿಂದ ಗುರು ಹೇಳುವ ಜ್ಞಾನ ನಿಜವಾದ ಜ್ಞಾನ. ಇಲ್ಲಿ ಕೃಷ್ಣ ತಾನಾಗಿಯೇ ಅರ್ಜುನನಿಗೆ\nಅಪೂರ್ವವಾದ ಜ್ಞಾನವನ್ನು ಹೇಳುತ್ತಿದ್ದಾನೆ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಹಿಂದೆ ಹೇಳಿದ ಕ್ಷೇತ್ರ(ಪ್ರಕೃತಿ-ಲಕ್ಷ್ಮಿ) ಮತ್ತು\nಕ್ಷೇತ್ರಜ್ಞನಾರಾಯಣ)ರ ವಿಚಾರವನ್ನು ಇನ್ನೂ ವಿವರವಾಗಿ ಹೇಳುತ್ತೇನೆ. ಏಕೆಂದರೆ ಅದು ತಿಳಿದುಕೊಳ್ಳಬೇಕಾದ\nವಿಚಾರದಲ್ಲೇ ಅತ್ಯಂತ ಮುಖ್ಯವಾದ ವಿಚಾರ”",
  "13.35": "[ಬನ್ನಂಜೆಯವರ ಭಾಷ್ಯದಲ್ಲಿ ಹದಿಮೂರನೇ ಅಧ್ಯಾಯವು ೩೪ ಶ್ಲೋಕಗಳೊಂದಿಗೆ ಮುಕ್ತಾಯಗೊಳ್ಳುತ್ತದೆ. ೧೩.೩೫ನೆಯ ಶ್ಲೋಕವು ಅವರ ಪಾಠದಲ್ಲಿಲ್ಲ; ಇದು ಹಿಂದಿನ ಶ್ಲೋಕದಲ್ಲೇ ಅಡಕವಾಗಿದೆ.]",
  "14.1": "ಅಂದರೆ “ಯಾರ ಕಟಾಕ್ಷದ ಬಲದಿಂದ ಇಡಿಯ ಸೃಷ್ಟಿ-ಸ್ಥಿತಿ-ಸಂಹಾರವನ್ನು ಲಕ್ಷ್ಮಿ ಮಾಡುತ್ತಾಳೋ, ಅಂತಹ\nಲಕ್ಷ್ಮಿಯ ಪತಿಯಾದ ನಾರಾಯಣನಿಗೆ ನಮಸ್ಕಾರ” ಎಂದು. ಇಲ್ಲಿ ಲಕ್ಷ್ಮಿಯನ್ನು ಒಂದು ಸ್ತೋತ್ರದಲ್ಲಿ ಪೂರ್ಣ\nವರ್ಣನೆ ಮಾಡಿ, ಅಂತಹ ಲಕ್ಷ್ಮಿಯ ಪತಿಯಾದ ನಾರಾಯಣನಿಗೆ ನಮಸ್ಕಾರ ಎಂದು ಹೇಳಿದ್ದಾರೆ. ಆದ್ದರಿಂದ\nಲಕ್ಷ್ಮೀನಾರಾಯಣರ ಸ್ತುತಿಯೇ ಲಕ್ಷ್ಮಿಸ್ತುತಿ, ಹೊರತು ಕೇವಲ ಲಕ್ಷ್ಮಿ ಸ್ತುತಿ ಅಲ್ಲ. ಇದಕ್ಕೆ ಮೂಲ-ಗೀತೆಯ\nಹನ್ನೆ ರಡು, ಹದಿಮೂರು ಮತ್ತು ಹದಿನಾಲ್ಕನೇ ಅಧ್ಯಾಯ. ಹನ್ನೆ ರಡನೇ ಅಧ್ಯಾಯದಲ್ಲಿ ಕೇವಲ ಲಕ್ಷ್ಮಿ ಉಪಾಸನೆ\nಮಾಡಿದರೆ ಖಂಡಿತವಾಗಿ ಆಕೆ ಒಲಿಯಳು ಎನ್ನುವ ಎಚ್ಚರವಿದ್ದರೆ, ಹದಿಮೂರನೇ ಅಧ್ಯಾಯದಲ್ಲಿ ಈ ಜಗತ್ತು\nಲಕ್ಷ್ಮೀನಾರಾಯಣರ ಸಂಯೋಗದಿಂದ ರಚನೆಯಾಯಿತು- ಆದ್ದರಿಂದ ನಾವೆಲ್ಲರೂ ಅವರ ಮಕ್ಕಳು ಎನ್ನುವ\nಸಂದೇಶವಿದೆ. ಭಗವಂತನ ಜೊತೆಗೆ ಸೃಷ್ಟಿ ಪ್ರಕ್ರಿಯೆಯಲ್ಲಿ ಲಕ್ಷ್ಮಿಯ ಅನುಸಂಧಾನ ಹೇಗೆ ಅನ್ನುವುದನ್ನು\nಹದಿನಾಲ್ಕನೇ ಅಧ್ಯಾಯ ವಿವರಿಸುತ್ತದೆ. ಲಕ್ಷ್ಮಿ, ಶ್ರೀ.ಭೂ-ದುರ್ಗ ಈ ಮೂರು ರೂಪದಲ್ಲಿ ಸತ್ವ-ರಜಸ್ಸು-\nತಮೋಗುಣಗಳ ನಿಯಾಮಕ ಶಕ್ತಿಯಾದ್ದರಿಂದ-ಅವಳ ಮಕ್ಕಳು ಸಾತ್ವಿಕರು-ರಾಜಸರು-ತಾಮಸರು ಎನ್ನುವ\nಮೂರು ಬಗೆ. ಈ ವಿಚಾರವನ್ನು ಮೊತ್ತಮೊದಲ ಬಾರಿ ಈ ಅಧ್ಯಾಯದಲ್ಲಿ ಹೇಳಲಾಗಿದೆ. ಹಿಂದಿನ ಯಾವ\nಅಧ್ಯಾಯದಲ್ಲೂ ಕೂಡಾ ತ್ರೈವಿದ್ಯರ ವಿವರ ಇಷ್ಟು ಸ್ಟ ಷ್ಟ ವಾಗಿ ಬಂದಿಲ್ಲ. ನಾವು ಈ ತ್ರಿಗುಣಗಳ ವಿಶ್ಲೇಷಣೆ\nಮಾಡಿ, ನಮ್ಮಲ್ಲಿರುವ ರಾಜಸ ಮತ್ತು ತಾಮಸ ಅಂಶವನ್ನು ತಿದ್ದಿಕೊಂಡು, ಹೇಗೆ ಸಾತ್ವಿಕ ದಾರಿಯಲ್ಲಿ\nಸಾಧನೆಯನ್ನು ಮಾಡಬಹುದು ಎನ್ನುವ ಅಂಶವನ್ನು ಈ ಅಧ್ಯಾಯದಲ್ಲಿ ಕಾಣಬಹುದು.\n\nಭಗವಾನುವಾಚ ।\nಪರಂ ಭೂಯಃ ಪ್ರವಕ್ಷ್ಯಾಮಿ ಜ್ಞಾನಾನಾಂ ಜ್ಞಾನಮುತ್ತಮಮ್‌ |।\nಯಜ್‌ ಜ್ಞಾತ್ವಾ ಮುನಯಃ ಸರ್ವೇ ಪರಾಂ ಸಿದ್ಧಿಮಿತೋ ಗತಾಃ॥೧॥\n\nಭಗವಾನ್‌ ಉವಾಚ-ಭಗವಂತ ಹೇಳಿದನು:\n\nಪರಮ್‌ ಭೂಯಃ ಪ್ರವಕ್ಷ್ಯಾಮಿ ಜ್ಞಾನಾನಾಮ್‌ ಜ್ಞಾನಮ್‌ ಉತ್ತಮಮ್‌ |\n\nಯತ್‌ ಜ್ಞಾತ್ವಾ ಮುನಯಃ ಸರ್ವೇ ಪರಾಮ್‌ ಸಿದ್ಧಿಮ್‌ ಇತಃ ಗತಾಃ -ತಿಳಿಯಬೇಕಾದ ಸಂಗತಿಗಳಲ್ಲಿ ಹಿರಿದಾದ\nತಿಳಿವನ್ನು ಇನ್ನಷ್ಟು ಹೇಳುತ್ತೇನೆ; ಎಲ್ಲಾ ಮುನಿಗಳು ಇದನ್ನರಿತು ಇಲ್ಲಿಂದ ಪರಮಪದವನ್ನೈದಿದರು.\n\nಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಇನ್ನೂ ಹೇಳುತ್ತೇನೆ” ಎಂದು. ಇದು ಬಹಳ ಮುಖ್ಯವಾದ ಮಾತು. ಸಾಮಾನ್ಯವಾಗಿ ಶಿಷ್ಯರು\nಒತ್ತಾಯ ಮಾಡಿದರೂ ಗುರುಗಳು ಹೇಳುವುದಿಲ್ಲ. ಗುರುಗಳಿಗೆ ಶಿಷ್ಯನ ಜ್ಞಾನ ತೃಷೆಯನ್ನು ಕಂಡು ಹೇಳಬೇಕು\nಅನ್ನಿಸಬೇಕು ಮತ್ತು ಅವರು ಖುಷಿಯಿಂದ ಹೇಳಬೇಕು. ಆಗ ಶಿಷ್ಯನಿಗೆ ಆ ವಿದ್ಯೆ ಫಲಿಸುತ್ತದೆ. ಹೀಗೆ ಜ್ಞಾನ\nತೃಷೆಯನ್ನು ಕಂಡು ಖುಷಿಯಿಂದ ಗುರು ಹೇಳುವ ಜ್ಞಾನ ನಿಜವಾದ ಜ್ಞಾನ. ಇಲ್ಲಿ ಕೃಷ್ಣ ತಾನಾಗಿಯೇ ಅರ್ಜುನನಿಗೆ\nಅಪೂರ್ವವಾದ ಜ್ಞಾನವನ್ನು ಹೇಳುತ್ತಿದ್ದಾನೆ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಹಿಂದೆ ಹೇಳಿದ ಕ್ಷೇತ್ರ(ಪ್ರಕೃತಿ-ಲಕ್ಷ್ಮಿ) ಮತ್ತು\nಕ್ಷೇತ್ರಜ್ಞನಾರಾಯಣ)ರ ವಿಚಾರವನ್ನು ಇನ್ನೂ ವಿವರವಾಗಿ ಹೇಳುತ್ತೇನೆ. ಏಕೆಂದರೆ ಅದು ತಿಳಿದುಕೊಳ್ಳಬೇಕಾದ\nವಿಚಾರದಲ್ಲೇ ಅತ್ಯಂತ ಮುಖ್ಯವಾದ ವಿಚಾರ” ಎಂದು. ಈ ಜಗತ್ತಿನ ಸೃಷ್ಟಿಯ ಹಿಂದೆ ತಂದೆ-ತಾಯಿಯಾಗಿ\nಲಕ್ಷ್ಮೀ-ನಾರಾಯಣರಿದ್ದಾರೆ. ಆದ್ದರಿಂದ ಕೇವಲ ತಂದೆಯ ಸ್ಮರಣೆ, ಅಥವಾ ಕೇವಲ ತಾಯಿಯ ಸ್ಮರಣೆ\nಮಾಡುವುದಕ್ಕಿಂತ, ತಂದೆ-ತಾಯಿಯರ ಸ್ಮರಣೆಯನ್ನು ತಿಳಿದು ಮಾಡುವುದು ಒಳಿತು. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಈ\nವಿಚಾರವನ್ನು ಇನ್ನೂ ವಿಸ್ತಾರವಾಗಿ ನಿನಗೆ ಹೇಳುತ್ತೇನೆ. ಏಕೆಂದರೆ ಇದು ಒಬ್ಬ ಮೋಕ್ಷ ಸಾಧನೆ ಮಾಡುವ ವ್ಯಕ್ತಿ\nತಿಳಿದುಕೊಳ್ಳಲೇಬೇಕಾದ ವಿಷಯ” ಎಂದು.\nಲಕ್ಷ್ಮೀ-ನಾರಾಯಣರನ್ನು ಸೃಷ್ಟಿ ಮೂಲದಲ್ಲಿ ಚಿಂತನೆ ಮಾಡದೇ ಮೋಕ್ಷ ಸಾಧನೆ ಅಸಾಧ್ಯ. “ಈ ಸಾಧನಾ\nಭೂಮಿಯಲ್ಲಿ ಹುಟ್ಟಿಬಂದು ಬ್ರಹ್ಮಸಾಕ್ಷಾತ್ಕಾರ ಪಡೆದ ಮುನಿಗಳೂ ಕೂಡಾ, ಇದನ್ನು ತಿಳಿದೇ ಜೀವನದ ಪರಮ\nಸಿದ್ಧಿಯಾದ ಮೋಕ್ಷವನ್ನು ಪಡೆದರು” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಇದನ್ನೇ ಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ಬಹಳ ಸ್ಪಷ್ಟವಾಗಿ\nವಿವರಿಸಲಾಗಿದೆ.\n",
  "14.2": "ಇದಮ್‌ ಜ್ಞಾನಮ್‌ ಅಪಾಶ್ರಿತ್ಯ ಮಮ ಸಾಧರ್ಮ್ಯಮ್‌ ಆಗತಾಃ ।\nಸರ್ಗೇ ಅಪಿ ನ ಉಪಜಾಯಂತೇ ಪ್ರಳಯೇ ನ ವ್ಯಥಂತಿ ಚ -ಈ ತಿಳಿವು ಗಳಿಸಿ ದುಗುಡ ದೂರರಾಗಿ ನನ್ನನ್ನು\nಹೋಲುವವರು ಸೃಷ್ಟಿ ಕಾಲದಲ್ಲಿ ಹುಟ್ಟು ವುದಿಲ್ಲ; ಪ್ರಳಯಕಾಲದಲ್ಲಿ ನೋಯುವುದಿಲ್ಲ.\n\nಈ ಶ್ಲೋಕದಲ್ಲಿ ಬಂದಿರುವ “ಅಪಾಶ್ರಿತ್ಯ' ಎನ್ನುವ ಪದ ವಿಶೇಷ ಅರ್ಥವನ್ನು ಕೊಡುವ ಪದ. \"ಅನ್ಯತ್‌ ಸರ್ವಂ\nಅಪಾಹಾಯಾಶ್ರಯಣಂ-ಅಪಾಶ್ರಯಣಃ “ಇನ್ಯಾರೂ ಇಲ್ಲ-ನೀನೇ ನನಗೆ ಆಶ್ರಯ” ಎಂದು ಭಗವಂತನಲ್ಲಿ\nಆಶ್ರಯ ಹೊಂದುವುದನ್ನು ಇಲ್ಲಿ 'ಅಪಾಶ್ರಿತ್ಯ' ಎಂದಿದ್ದಾರೆ. ದ್ವಾದಶ ಸ್ತೋತ್ರದಲ್ಲಿ ಹೇಳುವಂತೆ:\n\nಕುರು ಭುಂಕ್ಷ್ಷ ಚ ಕರ್ಮ ನಿಜಂ ನಿಯತಂ ಹರಿಪಾದವಿನಮ್ರಧಿಯಾ ಸತತಂ |\n\nಹರಿರೇವ ಪರೋ ಹರಿರೇವ ಗುರುಃ ಹರಿರೇವ ಜಗತ್ಪಿತೃಮಾತೃಗತಿಃ ॥ ೧॥\nಇದು “ಅಪಾಶ್ರಿತ್ಯ' ಪದದ ಮೂಲ ಅರ್ಥವನ್ನು ಹೇಳುತ್ತದೆ. ಇಲ್ಲಿ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಲಕ್ಷ್ಮೀ-ನಾರಾಯಣರು\nಜಗತ್ತಿನ ತಂದೆ ತಾಯಿ ಅನ್ನುವ ಜ್ಞಾನದಿಂದ ನನ್ನನ್ನು ಉಪಾಸನೆ ಮಾಡುವವರು, ನನ್ನಂತೆ ದಿವ್ಯ ಸ್ವಭಾವವನ್ನು\nಪಡೆಯುತ್ತಾರೆ” ಎಂದು. ಇಂತವರು ಸರ್ವದೋಷವನ್ನು ಕಳೆದುಕೊಂಡು, ತ್ರಿಗುಣಾತೀತ ಸ್ಥಿತಿಯಲ್ಲಿ\nಭಗವಂತನನ್ನು ಸೇರಿ ಭಗವಂತನಲ್ಲಿ ನೆಲೆಸುತ್ತಾರೆ. ಈ ಜಗತ್ತು ಸೃಷ್ಟಿಯಾಗುವುದೂ ಲಕ್ಷ್ಮೀ-ನಾರಾಯಣರಿಂದ\nಮತ್ತು ಹೋಗಿ ಸೇರುವುದೂ ಅವರನ್ನೆ . ಇದನ್ನು ತಿಳಿದವನು ಹುಟ್ಟು ಸಾವನ್ನು ದಾಟಬಲ್ಲ. ಆತ ಮರಳಿ ಎಂದೂ\nಈ ಸಂಸಾರ ಬಂಧದಲ್ಲಿ ಸೀಲುಕುವುದಿಲ್ಲ. ಇಲ್ಲಿ 'ಉಪಜಾಯತೆ' ಎನ್ನುವ ಪದ ಬಳಕೆಯಾಗಿದೆ. ಸಂಸ್ಕೃತದಲ್ಲಿ\n\"ಉಪ' ಅಂದರೆ \"ಉತ್ಕೃಷ್ಟ'.. ಆದ್ದರಿಂದ \"ಉಪಜಾಯತೆ' ಎಂದರೆ ಉತ್ಕೃಷ್ಟವಾದ ಜನನ. ಭಗವಂತನ ಅರಿವಿಗೋಸ್ಕರ ಈ\nದೇಹ ಧಾರಣೆ ಮಾಡಿ ಹುಟ್ಟುವುದು ಎತ್ತರದ ಹುಟ್ಟು. ಅಧ್ಯಾತ್ಮದ ಸಾಧನೆಯಿಂದ ಎತ್ತರಕ್ಕೇರುವ ಜನನ\n\"ಉಪಜನನ'. ತನ್ನ ಜೀವಮಾನದಲ್ಲಿ ಈ ಸೃಷ್ಟಿಯ ಮೂಲದ ಜ್ಞಾನವನ್ನು ಗಳಿಸಿದವ ಮತ್ತೆ ಮರಳಿ ಹುಟ್ಟಲಾರ.\nಆತ ಭಗವಂತನಲ್ಲಿ ನಿರಂತರ ವಾಸ ಮಾಡುವ ಪರಮ ಪದವನ್ನು ಪಡೆಯುತ್ತಾನೆ.\n",
  "14.3": "ಮಮ ಯೋನಿಃ ಮಹತ್‌ ಬ್ರಹ್ಮ ತಸ್ಮಿನ್‌ ಗರ್ಭಮ್‌ ದಧಾಮಿ ಅಹಮ್‌ ।\nಸಂಭವಃ ಸರ್ವಭೂತಾನಾಮ್‌ ತತಃ ಭವತಿ ಭಾರತ -ಚೇತನ ಪ್ರಕೃತಿ ನನ್ನ ಅರ್ಧಾಂಗಿ. ಅವಳಲ್ಲಿ ಸೃಷ್ಟಿಯ\nಬೀಜವನ್ನು ಬಿತ್ತುತ್ತೇನೆ. ಭಾರತಾ, ಎಲ್ಲಾ ಜೀವಿಗಳ ಹುಟ್ಟು ಅದರ ಮೂಲಕ ನಡೆಯುತ್ತದೆ.\n\nಇಲ್ಲಿ ಕೃಷ್ಣ ಬಹಳ ವಿಚಿತ್ರವಾದ ಒಂದು ಸಂಗತಿಯನ್ನು ಹೇಳುತ್ತಾನೆ. ಈ ಶ್ಲೋಕ ಅರ್ಥವಾಗಬೇಕಿದ್ದರೆ ನಾವು\nಮೊದಲು 'ಭಾ-ರತ' ರಾಗಬೇಕು. 'ರತ' ಅಂದರೆ ತತ್ವರತೆ. ನಾವು. ಭಗವಂತನಲ್ಲಿ ರತರಾಗಬೇಕು; ಜ್ಞಾನದ\nಮಾರ್ಗದಲ್ಲಿ ರತರಾಗಬೇಕು; ಭಕ್ತಿಯಿಂದ ಭರಿತರಾಗಿ ತುಂಬಿದ ಕೊಡವಾಗಬೇಕು; ವಿನೀತರಾಗಿರಬೇಕು. ಆಗ\nಸೃಷ್ಟಿಯ ಈ ಗುಟ್ಟು ಅರ್ಥವಾಗುತ್ತದೆ.\n\nಯಾವುದೇ ಒಂದು ವಸ್ತು ಸೃಷ್ಟಿಯಾಗಬೇಕಿದ್ದರೂ ಅಲ್ಲಿ ಒಂದಕ್ಕಿಂತ ಹೆಚ್ಚು ಕಾರಣಗಳು ಬೇಕು. ಜಡವಾದರೆ\nಅಲ್ಲಿ ಎರಡು ಕಾರಣಗಳು ಅಗತ್ಯ, ಉದಾಹರಣೆಗೆ ಒಂದು ಮಡಕೆ ಸೃಷ್ಟಿಯಾಗಬೇಕಿದ್ದರೆ ಅಲ್ಲಿ ಮೂಲದ್ರವ್ಯ(Raw materials) ಬೇಕು ಮತ್ತು ರೂಪ ಕೊಡುವ ಕುಂಬಾರ ಬೇಕು. ವನಸ್ಪತಿಗಳ ಸೃಷ್ಟಿ- ಜಡದೊಳಗೆ ಭಗವಂತ\nಜೀವವನ್ನು ಸೇರಿಸುವುದರ ಮೂಲಕ ಆಗುತ್ತದೆ. ಆದರೆ ಗರ್ಭದ ಮೂಲಕ ಹುಟ್ಟುವ 'ಚೇತನ ಸೃಷ್ಟಿ'ಗೆ\nಜಡದ್ರವ್ಯದೊಂದಿಗೆ ಸೃಷ್ಟಿ ಮಾಡತಕ್ಕಂತಹ ಒಂದು ಗಂಡು ಮತ್ತು ಒಂದು ಹೆಣ್ಣು ಬೇಕು. ಇಬ್ಬರ\nಸಮಾಗಮದಿಂದ ಮೂರನೆಯದು ಸೃಷ್ಟಿಯಾಗುತ್ತದೆ.\nಈ ಶ್ಲೋಕದಲ್ಲಿ \"ಮಮ ಯೋನಿಃ ಮಹತ್‌ ಬ್ರಹ್ಮ' ಎನ್ನುವಲ್ಲಿ ಬಂದಿರುವ 'ಯೋನಿ' ಮತ್ತು 'ಬ್ರಹ್ಮ' ಎನ್ನುವ\nಪದಗಳು ಅನೇಕ ಅರ್ಥವನ್ನು ಕೊಡುವ ಪದಗಳು. ಯಾವ ಸಂದರ್ಭದಲ್ಲಿ ಯಾವ ಅರ್ಥ ಹೊಂದಿಕೆಯಾಗುತ್ತದೆ\nಎಂದು ತಿಳಿದು ನಾವು ಶ್ಲೋಕವನ್ನು ಅರ್ಥ ಮಾಡಿಕೊಳ್ಳಬೇಕು. ಯೋನಿ- ಕಾರಣ, ಉತ್ಪತ್ತಿಸ್ಥಾನ, ಹೆಂಡತಿ\nಇತ್ಯಾದಿ ಅರ್ಥವನ್ನು ಕೊಡುತ್ತದೆ. ಅದೇ ರೀತಿ ಬ್ರಹ್ಮ- ಜೀವ, ಚತುರ್ಮುಖ, ಲಕ್ಷ್ಮಿ, ಭಗವಂತ ಇತ್ಯಾದಿ ಅನೇಕ\nಅರ್ಥವನ್ನು ಕೊಡುತ್ತದೆ... ಈ ಶ್ಲೋಕದಲ್ಲಿ. ಯೋನಿ ಅಂದರೆ ಹೆಂಡತಿ; 'ಮಹತ್‌ ಬ್ರಹ್ಮ' ಎಂದರೆ\nಚತುರ್ಮುಖನಿಗೂ ತಾಯಿಯಾಗಿರುವ ಶ್ರೀಲಕ್ಷ್ಮಿ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ ನಾನು ನನ್ನ ಪತ್ನಿಯಾದ ಚಿತ್‌ ಪ್ರಕೃತಿ\n(ಲಕ್ಷ್ಮಿನಯಲ್ಲಿ ಗರ್ಭದಾನ ಮಾಡುತ್ತೇನೆ. ಆ ಗರ್ಭ ಬೆಳೆದು ಸಮಸ್ತ ಜೀವಜಾತಗಳು ಸೃಷ್ಟಿಯಾಗುತ್ತವೆ” ಎಂದು.\nಇದು ನಮಗೆ ಹೊಸ ಸಂಗತಿ. ಏಕೆಂದರೆ ಋಗ್ವೇದದಲ್ಲಿ ಚತುರ್ಮುಖನ ಸೃಷ್ಟಿಯ ಬಗ್ಗೆ ಈ ರೀತಿ ಹೇಳಲಾಗಿದೆ:\n\nತಮಿದ್ಗರ್ಭಂ ಪ್ರಥಮಂ ದಧ್ರ ಆಪೋ ಯತ್ರ ದೇವಾಃ ಸಮಗಚ್ಛಂತ ವಿಶ್ವೇ।\n\nಅಜಸ್ಯ ನಾಭಾವಧ್ಯೇಕಮರ್ಪಿತಂ ಯಸ್ಮಿನ್ವಿಶ್ವಾನಿ ಭುವನಾನಿ ತಸ್ಥುಃ ॥ ೧೦.೮೨.೦೬॥\nಇಲ್ಲಿ “ಭಗವಂತನ ನಾಭಿ ಕಮಲದಿಂದ ಬ್ರಹ್ಮ ಹೊರ ಬಂದ” ಎಂದು ಹೇಳಲಾಗಿದೆ. ಚತುರ್ಮುಖನಿಂದ ಜೀವ\nಸೃಷ್ಟಿ ನಿರ್ಮಾಣವಾಯಿತು. ಆದ್ದರಿಂದ ಚತುರ್ಮುಖ ಜಗತ್ತಿನ ತಂದೆ ಎನ್ನುವ ವಿಚಾರವೂ ನಮಗೆ ತಿಳಿದಿದೆ.\nವೇದದಲ್ಲಿ ಇನ್ನೊಂದು ಕಡೆ(ಅಂಭ್ರಿಣೀಸೂಕ್ರ) ಹೀಗೆ ಹೇಳಿದ್ದಾರೆ:\n\nಅಹಂ ಸುವೇ ಪಿತರಮಸ್ಯ ಮೂರ್ಧನ್‌ ಮಮ ಯೋನಿರಪ್ಸ _೦ತಃ ಸಮುದ್ರೇ |\n\nತತೋ ವಿ ತಿಷ್ಠೇ ಭುವನಾನು ವಿಶ್ವೋ-ತಾಮೂಂ ದ್ಯಾಂ ವರ್ಷ್ಮ್ನಣೋಪ ಸ್ಪೃಶಾಮಿ | ೭॥\nಇದು ಲಕ್ಷ್ಮಿ ಹೇಳುವ ಮಾತು: “ನಾನು ಈ ಜಗತ್ತಿನ ತಂದೆಯಾದ ಚತುರ್ಮುಖನನ್ನು ನನ್ನ ನೆತ್ತೀಮೂರ್ಧನ್‌-\nಬೈತಲೆ)ಯಿಂದ ಹೆತ್ತೆ. ನನಗೂ ಕಾರಣನಾದ ಭಗವಂತ ಸಮುದ್ರದಲ್ಲಿದ್ದಾನೆ ” ಎಂದು. ಸಮಸ್ತ ಬ್ರಹ್ಮಾಂಡದ\nಸೃಷ್ಟಿ ಶಿವನಿಂದಾಯಿತು ಎಂದು ಇನ್ನೊಂದೆಡೆ ಹೇಳುತ್ತಾರೆ. ಶಾಸ್ತ್ರ ಪ್ರಕ್ರಿಯೆ ಗೊತ್ತಿಲ್ಲದಿದ್ದರೆ ಇದೆಲ್ಲವೂ ಬರಿಯ\nಗೊಂದಲ. ಮೋಕ್ಷ ಸಾಧನೆ ಮಾಡುವವರು ಇದನ್ನು ಸೂಕ್ಷ್ಮವಾಗಿ ವಿಶ್ಲೇಷಿಸಬೇಕು-ಆಗ ಸತ್ಯ\nಸಾಕ್ಷಾತ್ಕಾರವಾಗುತ್ತದೆ.\nಜೀವ-ಪ್ರಕೃತಿ-ಭಗವಂತ ಅನಾದಿ ಅನಂತ. ಸೃಷ್ಟಿ ಪೂರ್ವದಲ್ಲಿ ಸಮಸ್ತ ಪ್ರಪಂಚ ಸೂಕ್ಷ್ಮ ರೂಪದಲ್ಲಿ ಭಗವಂತನ\nಉದರದಲ್ಲಿತ್ತು. ಇದನ್ನು ಇನ್ನೂ ಸೂಕ್ಷ್ಮವಾಗಿ ನೋಡಿದರೆ- ಸಮಸ್ತ ವಿಶ್ವ ಲಕ್ಷ್ಮೀದೇವಿಯ ಉದರದಲ್ಲಿತ್ತು ಮತ್ತು\nಲಕ್ಷ್ಮಿ ಭಗವಂತನ ಉದರದಲ್ಲಿದ್ದಳು. ಭಗವಂತ ಲಕ್ಷ್ಮಿಯ ಉದರದಲ್ಲಿ ಸಮಸ್ತ ಜೀವಜಾತಗಳ ಬೀಜಕ್ಷೇಪ\nಮಾಡಿದ. ಕಮಲ ರೂಪದ ಇಡೀ ಬ್ರಹ್ಮಾಂಡ ಲಕ್ಷ್ಮಿಯ ನೆತ್ತಿಯ ಮೂಲಕ ಭಗವಂತನ ನಾಭಿಯಿಂದ\nಹೊರಚಿಮ್ಮಿತು. ಅದರಲ್ಲಿ ಚತುರ್ಮುಖನಿದ್ದ ಜೊತೆಗೆ ಅವ್ಯಕ್ತ ರೂಪದಲ್ಲಿ ಸಮಸ್ತ ದೇವತೆಗಳೂ, ಜೀವಜಾತರೂ\nಹುಟ್ಟಿದರು. ಈ ಕಾರಣದಿಂದ ಲಕ್ಷ್ಮೀನಾರಾಯಣರು ಸಮಸ್ತ ಜಗತ್ತಿನ ತಾಯಿ-ತಂದೆ. ಇಲ್ಲಿ ನಾವು\nಅರಿಯಬೇಕಾದ ಒಂದು ಮುಖ್ಯ ವಿಚಾರವೆಂದರೆ-ಸೃಷ್ಟಿ ಕ್ರಿಯೆ ಹಂತ ಹಂತವಾಗಿ ನಡೆದ ಕ್ರಿಯೆ. ಲಕ್ಷ್ಮೀ\n\nನಾರಾಯಣರ ಸಮಾಗಮದಿಂದ ನಿರ್ಮಾಣವಾದದ್ದು ಕೇವಲ ಅವ್ಯಕ್ತ ಸೃಷ್ಟಿ. ನಂತರ ಚತುರ್ಮುಖ ಬ್ರಹ್ಮ ಈ\nಸೂಕ್ಷ್ಮರೂಪಿ ಅವ್ಯಕ್ತ ಪ್ರಪಂಚಕ್ಕೆ(ಜೀವ ಜಾತಕ್ಕೆ) ಒಂದು ಮೂಲ ಸ್ಥೂಲರೂಪವನ್ನು ಕೊಟ್ಟು ಜಗತ್ತಿನ\nಪಿತಾಮಹನೆನಿಸಿದ. ತದನಂತರ ಶಿವನಿಂದ ಈ ಪ್ರಪಂಚ ಪೂರ್ಣ ಸ್ಥೂಲರೂಪವನ್ನು ಪಡೆಯಿತು. ಈ\nಪ್ರಕ್ರಿಯೆಯನ್ನು ನಾವು ಅರ್ಥ ಮಾಡಿಕೊಂಡರೆ ಇಲ್ಲಿ ಯಾವುದೇ ಗೊಂದಲವಿಲ್ಲ. ಚತುರ್ಮುಖ ಲಕ್ಷ್ಮಿಯ\nನೆತ್ತಿಯಿಂದ ಹುಟ್ಟಿದ್ದು ಹೌದು; ಆತ ಭಗವಂತನ ನಾಭಿಯಿಂದ ಹುಟ್ಟಿರುವುದೂ ಹೌದು; ಆತ ಜಗತ್ತಿನ ತಂದೆ\nಹೌದು; ಶಿವನಿಂದ ಈ ಸ್ಥೂಲ ಪ್ರಪಂಚ ನಿರ್ಮಾಣವಾದದ್ದೂ ಹೌದು; ಲಕ್ಷ್ಮೀ ನಾರಾಯಣರು ಸಮಸ್ತ\nಜೀವಜಾತದ ತಾಯಿ-ತಂದೆ ಕೂಡಾ ಹೌದು. ಈ ಕುರಿತ ವಿವರವನ್ನು 'ಮಹಾಭಾರತ ತಾತ್ಪರ್ಯ ನಿರ್ಣಯ'ದಲ್ಲಿ\nಸ್ಪಷ್ಟವಾಗಿ ವಿವರಿಸಲಾಗಿದೆ.\n\nಒಂದು ಚೇತನ[ಭೂತಿ(ಉನ್ನತಿ) ಉಳ್ಳ ಜೀವ]ದ ಸೃಷ್ಟಿಗೆ ಒಂದು ಗಂಡು ಒಂದು ಹೆಣ್ಣಿನ ಸಮಾಗಮ ಅಗತ್ಯ.\nಇದು ಸೃಷ್ಟಿ ಆರಂಭದಿಂದಲೇ ಬೆಳೆದುಕೊಂಡು ಬಂದ ಸಂಪ್ರದಾಯ. ಜಗತ್ತಿನ ಎಲ್ಲಾ ಸೃಷ್ಟಿಯ ಹಿಂದೆ\nಲಕ್ಷ್ಮೀನಾರಾಯಣರು ತಂದೆ ತಾಯಿಯಾಗಿ ನಿಂತಿದ್ದಾರೆ. ಈ ವಿಷಯವನ್ನು ಇನ್ನೂ ಸ್ಪಷ್ಟವಾಗಿ ಕೃಷ್ಣ ಮುಂದಿನ\nಶ್ಲೋಕದಲ್ಲಿ ವಿವರಿಸುತ್ತಾನೆ.",
  "14.4": "ಸರ್ವಯೋನಿಷು ಕೌಂತೇಯ ಮೂರ್ತಯಃ ಸಂಭವಂತಿ ಯಾಃ ।\n\nತಾಸಾಮ್‌ ಬ್ರಹ್ಮ ಮಹತ್‌ ಯೋನಿಃ ಅಹಮ್‌ ಬೀಜಪ್ರದಃ ಪಿತಾ -ಕೌಂತೇಯಾ, ಯಾವೆಲ್ಲಾ ಬಸಿರುಗಳಲ್ಲಿ\nಏನೆಲ್ಲಾ ರೂಪಗಳು ರೂಪುಗೊಳ್ಳುತ್ತವೋ- ಅವುಗಳಿಗೆಲ್ಗಾ ಚೇತನ ಪ್ರಕೃತಿಯೇ ತಾಯಿ; ನಾನೇ ಬೀಜ ಬಿತ್ತುವ\nತಂದೆ.\n\nಕೇವಲ ದೇವತೆಗಳು, ಮಾನವರಷ್ಟೇ ಅಲ್ಲ. ಸಮಸ್ತ ಜೀವಜಾತದ ಹುಟ್ಟಿನ ಹಿಂದೆ ತಂದೆ ತಾಯಿಯಾಗಿ ಲಕ್ಷ್ಮೀ-\nನಾರಾಯಣರಿದ್ದಾರೆ. ಎಲ್ಲವುದರ ತಾಯಿ-ಚೇತನ ಪ್ರಕೃತಿ ಲಕ್ಷ್ಮಿ. ಬೀಜ ಬಿತ್ತುವ ತಂದೆ ನಾರಾಯಣ. ಮುಂಡಕ\nಉಪನಿಷತ್ತಿನಲ್ಲಿ ಹೇಳುವಂತೆ:\nಪುಮಾನ್‌ ರೇತಃ ಸಿಂಚತಿ ಯೋಪಿತಾಯಾಂ ಬಹ್ವೀಃ ಪ್ರಜಾಃ ಪುರುಷಾತ್‌ ಸಂಪ್ರಸೂತಾಃ ॥| ೨.೨.೫॥\n\nಇಲ್ಲಿ 'ಪುಮಾನ್‌' ಎಂದರೆ ಗಂಡಿನಲ್ಲಿ ವಿಶೇಷವಾಗಿ ಸನ್ನಿಹಿತನಾಗಿರುವ ಭಗವಂತ ಮತ್ತು 'ಯೋಷಿತಾ' ಎಂದರೆ\nಹೆಣ್ಣಿನಲ್ಲಿ ವಿಶೇಷವಾಗಿ ಸನ್ನಿಹಿತಳಾಗಿರುವ ಲಕ್ಷ್ಮಿ. ಹೇಗೆ ಹೊಲದಲ್ಲಿ ಬೀಜ ಬಿತ್ತಿದರೆ ಅದು ಅಲ್ಲಿ ನಿಜವಾದ\nರೂಪವನ್ನು ತಾಳುತ್ತದೋ, ಹಾಗೇ ಭಗವಂತ ಜಡಪ್ರಕೃತಿಯ ಅಭಿಮಾನಿನಿಯಾದ ಶ್ರೀಲಕ್ಷ್ಮಿಯಲ್ಲಿ ಬೀಜಪ್ರದ\nಮಾಡುತ್ತಾನೆ. ತಾಯಿ ಲಕ್ಷ್ಮಿ ಆ ಬೀಜಕ್ಕೆ ಒಂದು ಆಕಾರ ಕೊಡುತ್ತಾಳೆ. ಈ ಅನುಸಂಧಾನ ಎಷ್ಟು ಭವ್ಯ. ಈ\nಕಾರಣಕ್ಕಾಗಿ ಹಿಂದಿನ ಕಾಲದ ಶಾಸ್ತ್ರಕಾರರು ಗರ್ಭಿಣಿ ಹೆಣ್ಣಿನ ದೇಹವನ್ನು ದೇವಾಲಯ ಎಂದೂ, ಆ ಗರ್ಭಿಣಿಯ\nಗರ್ಭವಿರುವ ಸ್ಥಳ ಗರ್ಭಗುಡಿ ಎಂತಲೂ, ಆ ಗರ್ಭದ ಒಳಗೆ ಸನ್ನಿಹಿತನಾಗಿ ಜೀವವನ್ನು ಬೆಳೆಸುತ್ತಿರುವವ\n\nಭಗವಂತ ಎಂತಲೂ ಗೌರವಿಸುತ್ತಿದ್ದರು. ಇದು ನಮ್ಮ ಪ್ರಾಚೀನರು ಪ್ರತಿಯೊಂದು ಕ್ರಿಯೆಯಲ್ಲೂ ಭಗವಂತನನ್ನು\nಅನುಸಂಧಾನ ಮಾಡುವ ಭವ್ಯತೆ. ಹೆಣ್ಣು ದೇವಾಲಯವಾಗುವುದು ಆಕೆ ಗರ್ಭಿಣಿಯಾದಾಗ. ಹಾಗಾಗಿ ಹೆಣ್ಣಿನ\nಸರ್ವ ಶ್ರೇಷ್ಠ ಭಯಕೆ ತಾನು ತಾಯಿಯಾಗಬೇಕು ಎನ್ನುವುದು. ಆಕೆಯ ಬಯಕೆಯ ಕೊನೆಯ ಗುರಿ ಮಾತೃತ್ವ.\nಲಕ್ಷ್ಮಿ ಆಕೆಯಲ್ಲಿ ಪೂರ್ಣ ಪ್ರಮಾಣದಲ್ಲಿ ಸನ್ನಿಹಿತಳಾಗುವುದು ಆಕೆ ಗರ್ಭವತಿಯಾದಾಗ. ಈ ಕಾರಣದಿಂದ\nದಾಂಪತ್ಯ ಅನ್ನುವುದು ಲಕ್ಷ್ಮೀನಾರಾಯಣರ ಆರಾಧನೆ. ದಾಂಪತ್ಯದಲ್ಲಿ ಗಂಡು ಹೆಣ್ಣಿನ ಸಮಾಗಮ ಎನ್ನುವುದು\nಲಕ್ಷ್ಮೀನಾರಾಯಣರ ಸಮಾಗಮ. ಇಲ್ಲಿ ನಮ್ಮ ಭಾಗ್ಯ ಎಂದರೆ ನಮ್ಮನ್ನು ಮಾಧ್ಯಮವಾಗಿ ಬಳಸಿ ಭಗವಂತ\nಸೃಷ್ಟಿ ಮಾಡುವುದು. ಈ ರೀತಿ ಸೃಷ್ಟಿಯಾಗುವಾಗ ಇಲ್ಲಿ ಬೇಕಾಗುವ ಮೂಲದ್ರವ್ಯದ ವಿಸ್ತಾರವಾದ\nವಿವರಣೆಯನ್ನು ಕೃಷ್ಣ ಮುಂದಿನ ಶ್ಲೋಕಗಳಲ್ಲಿ ನೀಡಿದ್ದಾನೆ.\n",
  "14.5": "ಸತ್ತ್ವಮ್‌ ರಜಃ ತಮಃ ಇತಿ ಗುಣಾಃ ಪ್ರಕೃತಿ ಸಂಭವಾಃ |\nನಿಬಧ್ನ ತಿ ಮಹಾಬಾಹೋ ದೇಹೇ ದೇಹಿನಮ್‌ ಅವ್ಯಯಮ್‌ - ಮಹಾಬಾಹೋ, ಸತ್ವ-ರಜಸ್ಸು -ತಮಸ್ಸು\nಎಂಬಿವು ಜಡಪ್ರಕೃತಿಯಿಂದ ಮೂಡಿಬಂದ ಗುಣಗಳು. ಅಳಿವಿರದ ಜೀವನನ್ನು ಇವು ದೇಹದಲ್ಲಿ ಕಟ್ಟಿಹಾಕುತ್ತವೆ.\n\nಈ ಪ್ರಪಂಚದ, ಸರ್ವ ಜೀವಜಾತದ ತಾಯಿಯಾದ ಪ್ರಕೃತಿ- ಗುಣತ್ರಯಮಾನಿನಿ. ಆದ್ದರಿಂದ ಪ್ರತಿಯೊಂದು\nಜೀವ ಹುಟ್ಟುವಾಗಲೂ ಕೂಡಾ ಸತ್ವ-ರಜಸ್ಸು ಮತ್ತು ತಮಸ್ಸೆಂಬ ಮೂರು ಗುಣಗಳೊಂದಿಗೆ ಹುಟ್ಟುತ್ತವೆ ಮತ್ತು\nಈ ಗುಣಗಳ ಪ್ರಭಾವದಲ್ಲಿ ಬೆಳೆಯುತ್ತವೆ. ಮೂರು ಗುಣಗಳಿಲ್ಲದೆ ಶುದ್ಧವಾದ ಏಕಗುಣದಿಂದ ಯಾವ ಜೀವವೂ\nಸೃಷ್ಟಿಯಾಗುವುದಿಲ್ಲ. ಜಡದಲ್ಲಿ ಕೂಡಾ ಈ ಮೂರು ಗುಣಗಳನ್ನು ಕಾಣುತ್ತೇವೆ. ಸದಾ ಊರ್ಧ್ವಮುಖ ಬೆಳಕನ್ನು\nಕೊಡುವ ಬೆಂಕಿ ಸತ್ವ; ಅಸ್ಪಷ್ಟತೆಯ ಸ್ಥಾನವಾದ ನೀರು ರಜಸ್ಸು ಮತ್ತು ಸದಾ ಕೆಳಮುಖವಾಗಿ ಸೆಳೆಯುವ\nಮಣ್ಣು-ತಮಸ್ಸು. ಜಗತ್ತಿನ ಎಲ್ಲಾ ವಸ್ತುಗಳೂ ಈ ಮೂರರ ಸಂಯೋಗ(combination). ಉದಾಹರಣೆಗೆ ಬತ್ತ.\nಅದನ್ನು ಭೂಮಿಯಲ್ಲಿ(ಮಣ್ಣು-ತಮಸ್ಸು] ಬಿತ್ತಿದೆವು. ಅಲ್ಲಿ ಅದಕ್ಕೆ ನೀರೆರೆದೆವು(ನೀರು-ರಜಸ್ಸು), ಅದು ಸೂರ್ಯನ\nಪ್ರಕಾಶವನ್ನು(ಸೂರ್ಯ-ಸತ್ವ) ಹೀರಿ ಚಿಗುರಿ ಬೆಳೆದು ಫಸಲನ್ನು ಕೊಟ್ಟಿತು. ಆ ಫಸಲನ್ನು ಕೊಯ್ದು ಅಕ್ಕಿಯನ್ನಾಗಿ\nಮಾಡಿದೆವು. ಅಕ್ಕಿಗೆ(ತಮಸ್ಸು) ನೀರನ್ನು(ರಜಸ್ಸು) ಸೇರಿಸಿ ಬೇಯಿಸಿ(ಶಾಖ-ಸತ್ವ) ಅನ್ನವನ್ನಾಗಿ ಮಾಡಿದೆವು.\nಅಕ್ಕಿ ಇರಲಿ, ಅನ್ನವಿರಲಿ, ಎಲ್ಲವೂ ಮಣ್ಣು-ನೀರು-ಬೆಂಕಿ ಈ ಮೂರರ ಸಂಯೋಜನೆ. ಹೀಗೆ ಸತ್ವ-ರಜಸ್ಸು ಮತ್ತು\nತಮಸ್ಸೆಂಬ ಗುಣತ್ರಯಗಳಿಂದ ಈ ಸಮಗ್ರ ಸೃಷ್ಟಿ ನಿರ್ಮಾಣವಾಗಿದೆ. ಹುಟ್ಟುವ ಪ್ರತಿಯೊಂದು ಜೀವಜಾತವನ್ನು\nಈ ಮೂರು ಗುಣಗಳು ಬಂಧಿಸುತ್ತವೆ. ಪ್ರತಿಯೊಬ್ಬರಲ್ಲೂ ಈ ಮೂರು ಗುಣಗಳ ಪ್ರಮಾಣ ಬೇರೆ\nಬೇರೆಯಾಗಿರುತ್ತದೆ. ಅತ್ಯಂತ ಸಾತ್ವಿಕನಾದ ಮೋಕ್ಷಯೋಗ್ಯ ಜೀವನಲ್ಲಿ ಕೂಡಾ ಈ ಮೂರು ಗುಣಗಳಿರುತ್ತವೆ.\nನೂರಕ್ಕೆ ನೂರು ಶುದ್ಧ ಸತ್ವಗುಣ ಒಬ್ಬ ವ್ಯಕ್ತಿಯಲ್ಲಿರುವುದಿಲ್ಲ. ಜಡದಲ್ಲಿ ನೋಡಿದರೆ ಬೆಂಕಿ-ಸತ್ವ. ಆದರೆ\nಅದರೊಂದಿಗೆ ಹೊಗೆ-ರಜಸ್ಸು, ಕಟ್ಟಿಗೆ-ತಮಸ್ಸು. ಸತ್ವ ಗುಣದ ಸಾಕ್ಷಾತ್ಮಾರವಿರುವುದೇ ರಜಸ್ಸು ಮತ್ತು\n\nತಮಸ್ಸಿನ ಮೂಲಕ. ಹೀಗೆ ಈ ಗುಣತ್ರಯಗಳ ಬಂಧನದಿಂದಾಗಿ ಸ್ವರೂಪತಃ ಹುಟ್ಟುಸಾವಿಲ್ಲದ ಜೀವ-ಸ್ಥೂಲ\nದೇಹವನ್ನು ಪಡೆದು ಹುಟ್ಟುತ್ತಾನೆ ಮತ್ತು ಆ ದೇಹವನ್ನು ಕಳೆದುಕೊಂಡು ಸಾಯುತ್ತಾನೆ. ಹುಟ್ಟು ಸಾವಿಲ್ಲದ\nಮೋಕ್ಷವನ್ನು ಸೇರಲು ನಾವು ನಮ್ಮೊಂದಿಗಿರುವ ಈ ಮೂರು ಅಂತಃಶತ್ರುಗಳನ್ನು ಗೆಲ್ಲಬೇಕು.\n\nಇಲ್ಲಿ ವ್ಯಾಸರು \"ಮಹಾಬಾಹು' ಎನ್ನುವ ವಿಶೇಷಣವನ್ನು ಬಳಸಿದ್ದಾರೆ. “ನಿನ್ನನ್ನು ಬಂಧಿಸಿ ತಮ್ಮ ಇಷ್ಟದಂತೆ\nಕುಣಿಸುವ ಈ ತ್ರಿಗುಣಗಳನ್ನು ಗೆದೆಯುವ ಮಹಾಬಾಹುವಾಗು; ಕುಸ್ಸಿತವನ್ನು ನಿರಾಕರಣೆಮಾಡಿ ಅಧ್ಯಾತ್ಮದ\nಶೂರನಾಗು” ಎನ್ನುವ ಧ್ವನಿ ಈ ವಿಶೇಷಣದ ಹಿಂದಿದೆ.\n\nಇಡೀ ವಿಶ್ವ, ಈ ನಮ್ಮ ಬದುಕು, ಎಲ್ಲವೂ ಗುಣತ್ರಯದ ವಿಕಾರ. ನಮ್ಮ ಮನಸ್ಸು, ನಮ್ಮ ಚಿಂತನೆ, ನಮ್ಮ\nನಿರ್ಧಾರ, ನಮ್ಮ ಓದು, ನಮ್ಮ ನಂಬಿಕೆ, ಎಲ್ಲವೂ ಈ ಗುಣಗಳ ಪ್ರಭಾವದಿಂದ. ನಮ್ಮನ್ನು ಸರಿ ದಾರಿಯಲ್ಲಿ\nನಡೆಸುವುದೂ ತ್ರಿಗುಣಗಳು, ನಮ್ಮನ್ನು ದಾರಿ ತಪ್ಪಿಸುವುದೂ ಈ ತ್ರಿಗುಣಗಳು. ಮೂರು ದಾರಿಯಲ್ಲಿ ಯಾವ\nದಾರಿಯಲ್ಲಿ ಸಾಗಿದರೆ ಒಳಿತಾಗುತ್ತದೆ ಎನ್ನುವ ತೀರ್ಮಾನ ಮಾಡಿಕೊಂಡು ಆಯ್ಕೆ ಮಾಡುವ ಎಚ್ಚರ ನಮಗೆ\nಬರಬೇಕಾಗಿದ್ದರೆ, ನಾವು ಯಾವ ದಾರಿಯಲ್ಲಿ ಸಾಗುತ್ತಿದ್ದೇವೆ ಎನ್ನು ವ ಅರಿವು ನಮಗೆ ಬೇಕು. ಈ ಕಾರಣಕ್ಕಾಗಿ\nತ್ರಿಗುಣಗಳ ಅರಿವು ನಮಗೆ ಬಹಳ ಮುಖ್ಯ.\n\nಒಬ್ಬ ವ್ಯಕ್ತಿಯನ್ನು ನಿಯಂತ್ರಿಸುವ ಸಂಗತಿಗಳು ನಾಲ್ಕು. ಒಂದು ಅನಾದಿಕಾಲದಿಂದ ಜೀವದ ಜೊತೆಗೆ ಜೀವ\nಸ್ವರೂಪದಲ್ಲಿ ಸೇರಿಕೊಂಡಿರತಕ್ಕಂತಹ “ಸ್ವಭಾವ'. ಇದರ ಜೊತೆಗೆ ಸತ್ವ, ರಜಸ್ಸು, ತಮಸ್ಸು-ಈ ಮೂರು\n'ಪ್ರಭಾವ'ಗಳು. ಸ್ವಭಾವ ಎಂದೂ ಬದಲಾಗುವುದಿಲ್ಲ. ನಾವು ನಮ್ಮ ಸ್ವಭಾವವನ್ನು ಗುರುತಿಸಿಕೊಳ್ಳಬೇಕು.\nಆದರೆ ನಮ್ಮ ಸ್ವಭಾವ ಏನು ಎನ್ನುವುದು ನಮಗೆ ತಿಳಿಯುವುದೇ ಇಲ್ಲ! ಏಕೆಂದರೆ ಈ ಸ್ವಭಾವದ ಮೇಲೆ\nಮುಚ್ಚಳವಾಗಿ 'ಪ್ರಭಾವ' ಕೂತಿದೆ. ನಾವು ಸದಾ ಈ ಮುಚ್ಚಳದ ಪ್ರಭಾವವನ್ನೇ ನಮ್ಮ ಸ್ವಭಾವ ಎಂದು\nಭ್ರಮಿಸುತ್ತೇವೆ. ಆದರೆ ಅದು ನಮ್ಮ ನಿಜವಾದ ಸ್ವರೂಪ ಸ್ವಭಾವವಲ್ಲ-ಅದು ಪ್ರಭಾವ. ಇಡೀ\nಜೀವಮಾನದುದ್ದಕ್ಕೂ ನಮ್ಮ ಸ್ವಭಾವವೇನು ಎನ್ನುವುದು ನಮಗೆ ತಿಳಿಯದೇ ಹೋಗಬಹುದು. ಸ್ವಭಾವವೇನು\nಎಂದು ತಿಳಿಯದೆ ನಾವು ಈ ಪ್ರಭಾವದೊಳಗೆ ಬಿದ್ದು ಒದ್ದಾಡುತ್ತಿರುತ್ತೇವೆ. ನಮಗೆ ಈ ತ್ರಿಗುಣಗಳ ಪ್ರಭಾವ\nಹೇಗೆ ಕೆಲಸ ಮಾಡುತ್ತದೆ ಎಂದು ತಿಳಿಯದೇ ಇದ್ದರೆ- ನಮ್ಮನ್ನು ನಾವು ತಿದ್ದಿಕೊಳ್ಳಲು ಆಗುವುದಿಲ್ಲ. ಇಂದು\nನಾವು ನಮ್ಮ ಸ್ವಭಾವವನ್ನು ಮತ್ತು ಸತ್ವಗುಣವನ್ನು ಮೂಲೆಗುಂಪಾಗಿಸಿ, ರಜಸ್ಸು ಮತ್ತು ತಮಸ್ಸುಗಳ\nಹತೋಟಿಯಲ್ಲಿ ಬದುಕುತ್ತಿದ್ದೇವೆ.\n\nಮೊದಲು ನಾವು ನಮ್ಮನ್ನು ತಿದ್ದಿಕೊಳ್ಳಬೇಕು-ಸಮಾಜವನ್ನಲ್ಲ. ನಮ್ಮಲ್ಲಿ ಸತ್ವದ ಅಂಶ ಎಷ್ಟಿದೆ; ರಜಸ್ಸಿನ ಅಂಶ\nಎಷ್ಟಿದೆ; ತಮಸ್ಸಿನ ಅಂಶ ಎಷ್ಟಿದೆ ಎನ್ನುವುದನ್ನು ತಿಳಿದು, ನಮ್ಮ ನಡೆಯಲ್ಲಿ ಸತ್ವದ ಅಂಶವನ್ನು ಹೆಚ್ಚಾಗಿ ಬಳಸಿ,\nಅದರ ಅಂಶವನ್ನು ಹೆಚ್ಚಿಸಿಕೊಳ್ಳಲು ಪ್ರಯತ್ನಿಸಬೇಕು. ಹಿಂದೆ ನಡೆದ ಘಟನೆಗಳಲ್ಲಿ ನಾವು ಎಲ್ಲಿ ರಜಸ್ಸಿನ ಮತ್ತು\nತಮಸ್ಸಿನ ಪ್ರಭಾವದಿಂದ ತಪ್ಪಿದ್ದೇವೆ. ಎನ್ನುವ ಆತ್ಮಚಿಂತನೆ. ನಡೆಸಿ, ಮುಂದೆ. ಹಾಗಾಗದಂತೆ\nಎಚ್ಚರವಹಿಸಬೇಕು. ಈ ವಿಚಾರವನ್ನು ತಿಳಿದು ನಡೆದರೆ ನಾವು ನಮ್ಮನ್ನು ನಿಯಂತ್ರಿಸಿಕೊಂಡು ಬಹಳ\nಆನಂದದಿಂದ ಬದುಕಬಹುದು.\n\nಮುಂದಿನ ಶ್ಲೋಕಗಳಲ್ಲಿ ಕೃಷ್ಣ ಸತ್ವದ ಬದುಕು ಹೇಗಿರುತ್ತದೆ; ರಜಸ್ಸಿನ ಬದುಕು ಹೇಗಿರುತ್ತದೆ; ತಮಸ್ಸಿನ ಬದುಕು\nಹೇಗಿರುತ್ತದೆ ಎನ್ನುವುದನ್ನು ವಿವರಿಸುತ್ತಾನೆ. ತ್ರಿಗುಣದ ಕಟ್ಟಿನಲ್ಲಿ ಸಿಕ್ಕಿಹಾಕಿಕೊಂಡ ಜೀವರು, ಯಾವ ಕಟ್ಟಿನ\nಪ್ರಭಾವದಲ್ಲಿ ಹೇಗೆ ನೆಡೆದುಕೊಳ್ಳುತ್ತಾರೆ ಎನ್ನುವ ಅಂಶ ತಿಳಿದರೆ, ಸತ್ಯದ ದಾರಿಯಲ್ಲಿ ಸಾಗಲು ಪ್ರಯತ್ನ\nಮಾಡಬಹುದು. ಇದಕ್ಕೆ ಬಹಳ ಸುಂದರವಾದ ವಿಶ್ಲೇಷಣೆಯನ್ನು ಕೃಷ್ಣ ಮುಂದಿನ ಶ್ಲೋಕಗಳಲ್ಲಿ ನೀಡಿದ್ದಾನೆ.\n",
  "14.6": "ತತ್ರ ಸತ್ತ್ವಮ್‌ ನಿರ್ಮಲತ್ವಾತ್‌ ಪ್ರಕಾಶಕಮ್‌ ಅನಾಮಯಮ್‌ |\n\nಸುಖ ಸಂಗೇನ ಬಧ್ನಾತಿ ಜ್ಞಾನ ಸಂಗೇನ ಚ ಅನಘ -ಅವುಗಳಲ್ಲಿ ಸತ್ವಗುಣ ಪರಿಶುದ್ಧವಾದದ್ದು. ಆದ್ದರಿಂದ\nಜ್ಞಾನದ ಬೆಳಕು ನೀಡುವಂತಾದ್ದು; ಬೇನೆಗಳನ್ನು ನೀಗುವಂತಾದ್ದು. ಓ ಅನಘಾ, ಅದು ಸುಖದ ನಂಟಿನಿಂದ\nಮತ್ತು ತಿಳಿವಿನ ನಂಟಿನಿಂದ ಕಟ್ಟಿಹಾಕುತ್ತದೆ.\n\nಕಣ್ಮುಚ್ಚಿ ಕುಳಿತು ನಿನ್ನೊಳಗೆ ನಿನ್ನನ್ನು ನೋಡು. ನಿನ್ನೊಳಗೆ ನಡೆಯುವ ಮಾನಸಿಕ ಬೆಳವಣಿಗೆಗಳು,\nಚಿಂತನೆಗಳು, ಯೋಚನೆಗಳು, ಭಾವನೆಗಳನ್ನು ನೋಡು. ಸತ್ವ ಗುಣದ ಪ್ರಭಾವ ನಿನ್ನ ಮೇಲೆ ಆಗಿದ್ದರೆ-\nನಿನ್ನೊಳಗೆ ನೀನು ಸ್ವಚ್ಛ, ನಿರ್ಮಲ ನಿರಾಳವಾದ ಪ್ರಜ್ವಲಿಸುವ ಬೆಳಕನ್ನು ಕಾಣುತ್ತೀಯ. ನಮ್ಮ ಅಂತರಂಗ\nಪ್ರಪಂಚಕ್ಕೆ ಪೂರ್ಣ ವಿದ್ಯುತ್‌ ಸಂಪರ್ಕವಾಗಿದೆ, ದೀಪವನ್ನು, ಆ ದೀಪವನ್ನು ನಿಯಂತ್ರಿಸುವ ಅನೇಕ ಸ್ವಿಚ್‌\nಅಳವಡಿಸಲಾಗಿದೆ. ಇಲ್ಲಿ ನಿರಂತರ ವಿದ್ಯುತ್‌ ಸರಬರಾಜಿದೆ. ಆದರೆ ನಮಗೆ ಈ ಸ್ವಿಚ್‌ ಎಲ್ಲಿದೆ ಎನ್ನುವುದು\nಗೊತ್ತಿಲ್ಲ. ಆದ್ದರಿಂದ- ಎಲ್ಲಾ ಇದ್ದರೂ ಸದಾ ನಮ್ಮೊಳಗೆ ಕತ್ತಲು ಆವರಿಸಿಕೊಂಡಿರುತ್ತದೆ. ನಾವು ಅದನ್ನು\nಉಪಯೋಗಿಸುವುದೇ ಇಲ್ಲ. ನಮ್ಮಲ್ಲಿ ಸತ್ವಗುಣ ಜಾಗೃತವಾದಾಗ ನಮಗೆ ಈ ಸ್ವಿಚ್‌ ಸಿಗುತ್ತದೆ. ಅದರಿಂದ\nಯಾವುದೇ ದೋಷವಿಲ್ಲದ ಜ್ಞಾನದ ಬೆಳಕು ನಮ್ಮೊಳಗೆ ಬೆಳಗುತ್ತದೆ.\n\nಸತ್ವದ ಗುಣ ಜಾಗೃತವಾದಾಗ ನಮ್ಮಲ್ಲಿ ಅಂತರಂಗದ ಆನಂದ ತುಂಬಿ ತುಳುಕುತ್ತಿರುತ್ತದೆ. ಈ ಅನುಭವ\nಹೆಚ್ಚಿನವರಿಗೆ ಆಗಿರುತ್ತದೆ. ಉದಾಹರಣೆಗೆ: ಕೆಲವೊಮ್ಮೆ ನಾವು ಹೇಳುವುದಿದೆ: “ಏಕೋ ಇಂದು ಬಹಳ\nಸಂತೋಷವಾಗುತ್ತಿದೆ” ಎಂದು. ಅಲ್ಲಿ ಏನೂ ವಿಶೇಷ ಕಾರಣವಿರುವುದಿಲ್ಲ. ಆದರೆ ಅಂತರಂಗದ ಆನಂದ ಹೊರ\nಹೊಮ್ಮುವುದನ್ನು ನಾವು ಅನುಭವಿಸುತ್ತಿರುತ್ತೇವೆ ಅಷ್ಟೆ. ಇದು ಸತ್ವ ಗುಣದ ಜಾಗೃತಾವಸ್ಥೆ. ಜ್ಞಾನದಿಂದ ಬರುವ\nಸುಖವೆಲ್ಲವೂ ಸಾತ್ವಿಕ.\n\nಇಲ್ಲಿ ಒಂದು ಎಚ್ಚರವನ್ನು ಕೃಷ್ಣ ಕೊಡುತ್ತಾನೆ. ಸತ್ವಗುಣ ನಮ್ಮಲ್ಲಿ ಜಾಗೃತವಾಗಬೇಕಾದರೆ ನಾವು\n\"ಅನಘ'ರಾಗಬೇಕು. ಪಾಪ ಸ್ಪರ್ಶ ನಮ್ಮಲ್ಲಿದ್ದರೆ-ಸತ್ವಗುಣ ಜಾಗೃತವಾಗದು. ಅದಕ್ಕಾಗಿ ನಾವು ಪಾಪ\nದೂರರಾಗಬೇಕು. ಪಾಪ ಸ್ಪರ್ಶ ಎಷ್ಟು ಹೆಚ್ಚಾಯಿತೋ- ಅಷ್ಟು ಸತ್ವ ದೂರ ಹೋಗುತ್ತದೆ.\n\nಮೋಕ್ಷ ಸಾಧನೆಯಲ್ಲಿ ಸತ್ವಗುಣ ಸಾಧನವಾದರೂ ಕೂಡಾ, ಇದು ತ್ರಿಗುಣಗಳಲ್ಲಿ ಒಂದು. ಆದ್ದರಿಂದ ಸತ್ವಗುಣ\nಕೂಡಾ ಬಂಧಕವಾಗಬಹುದು. ಇದು ಸುಖದ ನಂಟಿನಿಂದ ಮತ್ತು ತಿಳಿವಿನ ನಂಟಿನಿಂದ ನಮ್ಮನ್ನು ಕಟ್ಟಿ\n\nಹಾಕಬಹುದು. ಉದಾಹರಣೆಗೆ: ಜ್ಞಾನ ಸಾಧನೆ ಸಾತ್ವಿಕ ಗುಣ. ಇಲ್ಲಿ ಭಗವಂತನ ವಿಷಯವಲ್ಲದ ಜ್ಞಾನ\nಸಾಧನೆಯ ನಂಟಿನಲ್ಲಿ ನಾವು ಬಿದ್ದರೆ-ಆಗ ಅದು ಬಂಧಕವಾಗುತ್ತದೆ. ನಾವು ಯಾವುದೋ ಸಂಶೋಧನೆ,\nಅನ್ವೇಷಣೆಯಲ್ಲಿ ಮುಳುಗಿದ್ದರೆ. ಅದು. ನಮ್ಮನ್ನು ಮೋಕ್ಷದತ್ತ ಕೊಂಡೊಯ್ಯಲಾರದು. ನಾವು. ಆ\nಸಂಶೋಧನೆಯಲ್ಲಿ ಬರುವ ಫಲಿತಾಂಶದ ಸುಖದ ನಂಟಿನಲ್ಲಿ ಸಿಲುಕಿ ಸತ್ವಗುಣದ ಬಂಧನಕ್ಕೊಳಗಾಗಬಹುದು.\nಮೋಕ್ಷ ಸಾಧನೆಯಲ್ಲಿ ನಾವು ಸತ್ವವನ್ನೂ ದಾಟಬೇಕು. ಏಕೆಂದರೆ ಮೋಕ್ಷ ತ್ರಿಗುಣಾತೀತ. ಕೃಷ್ಣ ಇಲ್ಲಿ ಸತ್ವ\nಗುಣವನ್ನು \"ಬದ್ದಾತಿ' ಎಂದಿದ್ದಾನೆ. ಏಕೆಂದರೆ ಈ ಬಂಧನ ಸುಲಭದಲ್ಲಿ ಬಿಡಿಸಿಕೊಳ್ಳಬಹುದಾದ ಬಂಧನ. ಅದು\nಎಂದೂ ನಮ್ಮನ್ನು ಕೆಳಕ್ಕೆಳೆಯುವುದಿಲ್ಲ. [ಆದರೆ ರಜಸ್ಸು ಮತ್ತು ತಮಸ್ಸು 'ನಿಬಧ್ನಾತಿ' ಎಂದು ಕೃಷ್ಣ ಮುಂದಿನ\nಶ್ಲೋಕಗಳಲ್ಲಿ ಉಲ್ಲೇಖಿಸಿದ್ದಾನೆ], ಯಾವ ಸತ್ವ ಭಗವಂತನ ಕಡೆಗೆ ಹೋಗದೆ ನಮ್ಮನ್ನು ಬಂಧನದಲ್ಲಿ\n\nಸುತ್ತಾಡಿಸುತ್ತದೋ- ಆ ಸತ್ವದಿಂದ ನಾವು ಪಾರಾಗಬೇಕು.",
  "14.7": "ರಜಃ ರಾಗಾತ್ಮಕಮ್‌ ವಿದ್ಧಿ ತೃಷ್ಣಾ ಸಂಗ ಸಮುದ್ಧವಮ್‌ ।\nತತ್‌ ನಿಬಧ್ನಾತಿ ಕೌಂತೇಯ ಕರ್ಮಸಂಗೇನ ದೇಹಿನಮ್‌--ರಜೋಗುಣ ರಂಜಿಸುವಂತಾದ್ದು, ಆಸೆ-ಆಸಕ್ತಿಗಳನ್ನು\nಹುಟ್ಟಿಸುವಂತಾದ್ದು ಎಂದು ತಿಳಿ. ಕೌಂತೇಯಾ, ಅದು ಜೀವನನ್ನು ಕರ್ಮದ ನಂಟಿನಿಂದ ಕಟ್ಟಿಹಾಕುತ್ತದೆ.\n\nರಜಸ್ಸು ಅಂದರೆ “ರಾಗ'. ಒಂದು ವಸ್ತುವನ್ನು ತುಂಬಾ ಇಷ್ಟಪಡುವುದು, ಬಯಕೆಗಳ ಸರಮಾಲೆ- ಹೀಗೆ ಎಲ್ಲಾ\nಪಂಚೇಂದ್ರಿಯಗಳ ಬಯಕೆ ರಜೋಗುಣದ ಪ್ರಭಾವದಿಂದ ಬರುವಂತಾದ್ದು. ಇದು ತೃಷ್ಣಾ ಮತ್ತು ಸಂಗಕ್ಕೆ\nಕಾರಣ. ಇಲ್ಲಿ ತೃಷ್ಣಾ ಎಂದರೆ ಬೇಕು-ಬೇಕು ಎನ್ನುವ ದಾಹ. ಸಂಗ ಎಂದರೆ ಒಂದು ವಸ್ತುವಿನ ನಿರಂತರ\nಒಡನಾಟ. ರಜೋಗುಣ ಬಯಕೆಯನ್ನು ಹುಟ್ಟಿಸುತ್ತದೆ. ಆ ಬಯಕೆಯಿಂದ ಒಡನಾಟ, ಒಡನಾಟದಿಂದ ಅದು\nಅಂಟಿಕೊಳ್ಳುವಂತೆ ಮಾಡುತ್ತದೆ. ಹೀಗೆ ಹಂತ ಹಂತವಾಗಿ ರಜೋಗುಣ ನಮ್ಮನ್ನು ಬಿಡಿಸಿಕೊಳ್ಳಲಾಗದ\nಬಂಧನಕ್ಕೊಳಪಡಿಸುತ್ತದೆ(ನಿಬಧ್ನಾತಿ). ಇದರ ಪ್ರಭಾವದಿಂದ ನಾವು ಜ್ಞಾನದ ಬಯಕೆ ಇಲ್ಲದ ಕರ್ಮಸಂಗ\nಮಾಡಲಾರಂಭಿಸುತ್ತೇವೆ. ಉದಾಹರಣೆಗೆ: ದುಡ್ಡಿಗಾಗಿ ಹೋರಾಟ, ದುಡ್ಡಿಗಾಗಿ. ಇಡೀ ಬದುಕನ್ನು\nಮೀಸಲಿಡುವುದು. ದುಡ್ಡೇ ಪ್ರಪಂಚ ಎಂದು ಹೋರಾಡುವುದು, ಇತ್ಯಾದಿ. ಇದು ರಜಸ್ಸಿ ನ ಗಾಢವಾದ ಬಂಧನದ\nಪ್ರಭಾವ.",
  "14.8": "ತಮಃ ತು ಅಜ್ಞಾನಜಮ್‌ ವಿದ್ಧಿ ಮೋಹನಂ ಸರ್ವದೇಹಿನಾಮ್‌ |\n\nಪ್ರಮಾದ ಆಲಸ್ಯ ನಿದ್ರಾಭಿಃ ತತ್‌ ನಿಬಧ್ನಾತಿ ಭಾರತ -- ಎಲ್ಲಾ ಜೀವಿಗಳಿಗೆ ಅಜ್ಞಾನ ನೀಡುವಂತಾದ್ದು,\nಭ್ರಮೆಗೊಳಿಸುವಂತಾದ್ದು- ತಮೋಗುಣ ಎಂದು ತಿಳಿ. ಭಾರತಾ, ಅದು ಮೈಮರೆವು, ಸೋಮಾರಿತನ ಮತ್ತು\nನಿದ್ದೆಗಳಿಂದ ಕಟ್ಟಿಹಾಕುತ್ತದೆ.\n\nಏನೂ ಗೊತ್ತಿಲ್ಲದೆ ಇರುವುದು ತಮಸ್ಸು. ತಮೋಗುಣದಿಂದ ಅಜ್ಞಾನ ಹುಟ್ಟುತ್ತದೆ. ಅದು ಎಷ್ಟು ಬಲಿಷ್ಟ ಎಂದರೆ-\nಅದು ನನ್ನಲ್ಲಿ ಜ್ಞಾನವಿಲ್ಲ, ನಾನು ಅಜ್ಞಾನಿ ಎನ್ನುವ ಜ್ಞಾನವೂ ಬಾರದಂತೆ ಮಾಡಬಲ್ಲದು. ಇದು ಅತ್ಯಂತ\nಭಯಾನಕ. ನನಗೆ ಏನೂ ಗೊತ್ತಿಲ್ಲ ಅನ್ನುವ ವಿಷಯ ಕೂಡಾ ನನಗೆ ಗೊತ್ತಿಲ್ಲದೇ ಇರುವುದು ತಮೋಗುಣದಿಂದ.\nಇದು ಸಮಸ್ತರನ್ನು ಭ್ರಮೆಯಲ್ಲಿ ಸಿಲುಕಿಹಾಕಿಸುವ ಗುಣ. ತಮಸ್ಸು ನಾವು ಬಿಡಿಸಿಕೊಳ್ಳಲಾಗದ ಮೂರು\nಕಟ್ಟಿನಿಂದ ನಮ್ಮನ್ನು ಬಂಧಿಸುತ್ತದೆ. ಅವುಗಳೆಂದರೆ ನಿದ್ದೆ, ಆಲಸ್ಯ ಮತ್ತು ಪ್ರಮಾದ. ಎಚ್ಚರದಲ್ಲೂ\nಎಚ್ಚರವಿಲ್ಲದೇ ಬದುಕುವುದು ಪ್ರಮಾದ. ತಪ್ಪು ಮಾಡುವುದು ತಪ್ಪಲ್ಲ, ಆದರೆ ತಪ್ಪು ಮಾಡಿಯೂ ತಿದ್ದಿಕೊಳ್ಳದೇ\nಇರುವುದು ಪ್ರಮಾದ. ಇದಕ್ಕೆಲ್ಲಾ ಕಾರಣ ನಮ್ಮಲ್ಲಿರುವ ತಮೋಗುಣ.",
  "14.9": "' ಆದರೆ, ಹಿಂದಿಯಲ್ಲಿ “ತಕ ಆಗಿದೆ. ಜರ್ಮನ್‌\nಭಾಷೆಯಲ್ಲಿ ಇದು. \"606ಗ' ಆಗಿದೆ. ಕನ್ನ ಡದಲ್ಲಿ ಉಪ್ಪರಿಗೆ ಅನ್ನು ವಲ್ಲಿ \"ಉಪ' - \"ಮೇಲೆ' ಎನ್ನು ವ ಅರ್ಥವನ್ನು\nಕೊಡುತ್ತದೆ]. ಆದ್ದರಿಂದ \"ಉಪಜಾಯತೆ' ಎಂದರೆ ಉತ್ಕೃಷ್ಟವಾದ ಜನನ. ಭಗವಂತನ ಅರಿವಿಗೋಸ್ಕರ ಈ\nದೇಹ ಧಾರಣೆ ಮಾಡಿ ಹುಟ್ಟುವುದು ಎತ್ತರದ ಹುಟ್ಟು. ಅಧ್ಯಾತ್ಮದ ಸಾಧನೆಯಿಂದ ಎತ್ತರಕ್ಕೇರುವ ಜನನ\n\"ಉಪಜನನ'. ತನ್ನ ಜೀವಮಾನದಲ್ಲಿ ಈ ಸೃಷ್ಟಿಯ ಮೂಲದ ಜ್ಞಾನವನ್ನು ಗಳಿಸಿದವ ಮತ್ತೆ ಮರಳಿ ಹುಟ್ಟಲಾರ.\nಆತ ಭಗವಂತನಲ್ಲಿ ನಿರಂತರ ವಾಸ ಮಾಡುವ ಪರಮ ಪದವನ್ನು ಪಡೆಯುತ್ತಾನೆ.\n\nಮಮ ಯೋನಿರ್ಮಹದ್‌ ಬ್ರಹ್ಮ ತಸಿ ಟಸ್‌ ಗರ್ಭಂ ದಧಾಮ್ಯಹಮ್‌ |\nಸಂಭವಃ ಸರ್ವಭೂತಾನಾಂ ತತೋ ಭವತಿ ಭಾರತ ॥೩॥\n\nಇಲ್ಲಿ ಕೃಷ್ಣ ಬಹಳ ವಿಚಿತ್ರವಾದ ಒಂದು ಸಂಗತಿಯನ್ನು ಹೇಳುತ್ತಾನೆ. ಈ ಶ್ಲೋಕ ಅರ್ಥವಾಗಬೇಕಿದ್ದರೆ ನಾವು\nಮೊದಲು 'ಭಾ-ರತ' ರಾಗಬೇಕು. 'ರತ' ಅಂದರೆ ತತ್ವರತೆ. ನಾವು. ಭಗವಂತನಲ್ಲಿ ರತರಾಗಬೇಕು; ಜ್ಞಾನದ\nಮಾರ್ಗದಲ್ಲಿ ರತರಾಗಬೇಕು; ಭಕ್ತಿಯಿಂದ ಭರಿತರಾಗಿ ತುಂಬಿದ ಕೊಡವಾಗಬೇಕು; ವಿನೀತರಾಗಿರಬೇಕು. ಆಗ\nಸೃಷ್ಟಿಯ ಈ ಗುಟ್ಟು ಅರ್ಥವಾಗುತ್ತದೆ.\n\nಯಾವುದೇ ಒಂದು ವಸ್ತು ಸೃಷ್ಟಿಯಾಗಬೇಕಿದ್ದರೂ ಅಲ್ಲಿ ಒಂದಕ್ಕಿಂತ ಹೆಚ್ಚು ಕಾರಣಗಳು ಬೇಕು. ಜಡವಾದರೆ\nಅಲ್ಲಿ ಎರಡು ಕಾರಣಗಳು ಅಗತ್ಯ, ಉದಾಹರಣೆಗೆ ಒಂದು ಮಡಕೆ ಸೃಷ್ಟಿಯಾಗಬೇಕಿದ್ದರೆ ಅಲ್ಲಿ ಮೂಲದ್ರವ್ಯ(Raw materials) ಬೇಕು ಮತ್ತು ರೂಪ ಕೊಡುವ ಕುಂಬಾರ ಬೇಕು. ವನಸ್ಪತಿಗಳ ಸೃಷ್ಟಿ- ಜಡದೊಳಗೆ ಭಗವಂತ\nಜೀವವನ್ನು ಸೇರಿಸುವುದರ ಮೂಲಕ ಆಗುತ್ತದೆ. ಆದರೆ ಗರ್ಭದ ಮೂಲಕ ಹುಟ್ಟುವ 'ಚೇತನ ಸೃಷ್ಟಿ'ಗೆ\nಜಡದ್ರವ್ಯದೊಂದಿಗೆ ಸೃಷ್ಟಿ ಮಾಡತಕ್ಕಂತಹ ಒಂದು ಗಂಡು ಮತ್ತು ಒಂದು ಹೆಣ್ಣು ಬೇಕು. ಇಬ್ಬರ\nಸಮಾಗಮದಿಂದ ಮೂರನೆಯದು ಸೃಷ್ಟಿಯಾಗುತ್ತದೆ.\nಈ ಶ್ಲೋಕದಲ್ಲಿ \"ಮಮ ಯೋನಿಃ ಮಹತ್‌ ಬ್ರಹ್ಮ' ಎನ್ನುವಲ್ಲಿ ಬಂದಿರುವ 'ಯೋನಿ' ಮತ್ತು 'ಬ್ರಹ್ಮ' ಎನ್ನುವ\nಪದಗಳು ಅನೇಕ ಅರ್ಥವನ್ನು ಕೊಡುವ ಪದಗಳು. ಯಾವ ಸಂದರ್ಭದಲ್ಲಿ ಯಾವ ಅರ್ಥ ಹೊಂದಿಕೆಯಾಗುತ್ತದೆ\nಎಂದು ತಿಳಿದು ನಾವು ಶ್ಲೋಕವನ್ನು ಅರ್ಥ ಮಾಡಿಕೊಳ್ಳಬೇಕು. ಯೋನಿ- ಕಾರಣ, ಉತ್ಪತ್ತಿಸ್ಥಾನ, ಹೆಂಡತಿ\nಇತ್ಯಾದಿ ಅರ್ಥವನ್ನು ಕೊಡುತ್ತದೆ. ಅದೇ ರೀತಿ ಬ್ರಹ್ಮ- ಜೀವ, ಚತುರ್ಮುಖ, ಲಕ್ಷ್ಮಿ, ಭಗವಂತ ಇತ್ಯಾದಿ ಅನೇಕ\nಅರ್ಥವನ್ನು ಕೊಡುತ್ತದೆ... ಈ ಶ್ಲೋಕದಲ್ಲಿ. ಯೋನಿ ಅಂದರೆ ಹೆಂಡತಿ; 'ಮಹತ್‌ ಬ್ರಹ್ಮ' ಎಂದರೆ\nಚತುರ್ಮುಖನಿಗೂ ತಾಯಿಯಾಗಿರುವ ಶ್ರೀಲಕ್ಷ್ಮಿ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ ನಾನು ನನ್ನ ಪತ್ನಿಯಾದ ಚಿತ್‌ ಪ್ರಕೃತಿ\n(ಲಕ್ಷ್ಮಿನಯಲ್ಲಿ ಗರ್ಭದಾನ ಮಾಡುತ್ತೇನೆ. ಆ ಗರ್ಭ ಬೆಳೆದು ಸಮಸ್ತ ಜೀವಜಾತಗಳು ಸೃಷ್ಟಿಯಾಗುತ್ತವೆ” ಎಂದು.\nಇದು ನಮಗೆ ಹೊಸ ಸಂಗತಿ. ಏಕೆಂದರೆ ಋಗ್ವೇದದಲ್ಲಿ ಚತುರ್ಮುಖನ ಸೃಷ್ಟಿಯ ಬಗ್ಗೆ ಈ ರೀತಿ ಹೇಳಲಾಗಿದೆ:\n\nತಮಿದ್ಗರ್ಭಂ ಪ್ರಥಮಂ ದಧ್ರ ಆಪೋ ಯತ್ರ ದೇವಾಃ ಸಮಗಚ್ಛಂತ ವಿಶ್ವೇ।\n\nಅಜಸ್ಯ ನಾಭಾವಧ್ಯೇಕಮರ್ಪಿತಂ ಯಸ್ಮಿನ್ವಿಶ್ವಾನಿ ಭುವನಾನಿ ತಸ್ಥುಃ",
  "14.10": "ರಜಃ ತಮಃ ಚ ಅಭಿಭೂಯ ಸತ್ವಮ್‌ ಭವತಿ ಭಾರತ।\nರಜಃ ಸತ್ವಮ್‌ ತಮಃ ಚ ಏವ ತಮಃ ಸತ್ವಮ್‌ ರಜಃ ತಥಾ -ಭಾರತಾ, ರಜಸ್ಸು-ತಮಸ್ಸುಗಳನ್ನು ತಳ್ಳಿ ಸತ್ವಗುಣ\nಬಲಗೊಳ್ಳುತ್ತದೆ; ಸತ್ವ ತಮಸ್ಸುಗಳನ್ನು ತಳ್ಳಿ ರಜೋಗುಣ; ಹಾಗೆಯೇ ಸತ್ವ-ರಜಸ್ಸುಗಳನ್ನು ತಳ್ಳಿ ತಮೋಗುಣ.\n\nಗುಣತ್ರಯಗಳಿಗೆ ಒಂದು ವಿಶೇಷವಾದ ಶಕ್ತಿ ಇದೆ. ಏನೆಂದರೆ ಈ ಮೂರರಲ್ಲಿ ಯಾವುದೋ ಒಂದು ನಮ್ಮ\nಮನಸ್ಸಿನ ನಿಯಂತ್ರಣವನ್ನು ತೆಗೆದುಕೊಂಡು ಉಳಿದ ಎರಡು ಗುಣಗಳನ್ನು ಮುಚ್ಚಿ(suppresses)ಬಿಡುತ್ತದೆ.\nಮೂರರಲ್ಲಿ ಒಂದು ಗುಣ ನಮ್ಮ ಮನಸ್ಸನ್ನು ಸ್ವಾಧೀನಪಡಿಸಿಕೊಳ್ಳುತ್ತದೆ. ಆಗ ನಮ್ಮ ಮನಸ್ಸು ಆ ಗುಣಕ್ಕೆ\nತಕ್ಕಂತೆ ಕೆಲಸ ಮಾಡಲಾರಂಭಿಸುತ್ತದೆ. ತ್ರಿಗುಣಮಾನಿನಿ ಲಕ್ಷ್ಮಿ. ಆಕೆ ಯಾವುದೋ ಒಂದು ಗುಣಕ್ಕೆ ಉಳಿದ\nಎರಡು ಗುಣವನ್ನು ಮೀರಿಸಿ ಕೆಲಸ ಮಾಡುವ ಶಕ್ತಿ ಕೊಡುತ್ತಾಳೆ. ಹೀಗೆ ಒಂದು ಗುಣ ಉಳಿದೆರಡು ಗುಣಗಳನ್ನು\nಮುಚ್ಚಿ ಕೆಲಸ ಮಾಡಲಾರಂಭಿಸುತ್ತದೆ.\n\nನಮ್ಮಲ್ಲಿ ಯಾವ ಗುಣ ಜಾಗೃತವಾಗಿದೆ ಎಂದು ನಾವು ಗುರುತಿಸಿಕೊಳ್ಳಬೇಕು. ಆಗ ಆ ಗುಣದ\nಪ್ರಭಾವದಿಂದಾಗುವ ಅನಾಹುತವನ್ನು ತಪ್ಪಿ ಸಬಹುದು. ಇದನ್ನು ಗುರುತಿಸುವ ವಿಧಾನವನ್ನು ಕೃಷ್ಣ ಮುಂದಿನ\nಮೂರು ಶ್ಲೋಕಗಳಲ್ಲಿ ವಿವರಿಸುತ್ತಾನೆ.",
  "14.11": "ಸರ್ವದ್ವಾರೇಷು ದೇಹೇ ಅಸ್ಮಿನ್‌ ಪ್ರಕಾಶಃ ಉಪಜಾಯತೇ ।\nಜ್ಞಾನಮ್‌ ಯದಾ ತದಾ ವಿದ್ಯಾತ್‌ ವಿವೃದ್ಧಮ್‌ ಸತ್ತ್ವಮ್‌ ಇತಿ ಉತ -ಈ ದೇಹದಲ್ಲಿ ಎಲ್ಲಾ ಇಂದ್ರಿಯಗಳಲ್ಲೂ\nತಿಳಿವು ಬೆಳಕಾಗಿ ಮೂಡಿಬಂದಾಗ ಸತ್ವಗುಣ ಬಲಗೊಂಡಿದೆ ಎಂದು ತಿಳಿಯಬೇಕು.\n\nಸತ್ವಗುಣ ಜಾಗೃತವಾದಾಗ ನಮ್ಮೊಳಗೆ ಬೆಳಕು ತುಂಬಿದ ಅನುಭವವಾಗುತ್ತದೆ. ಈ ಬೆಳಕಿನ ಸಂಚಾರ ಎಲ್ಲಾ\nಇಂದ್ರಿಯಗಳ ಮೂಲಕ ಹೊರಬರುತ್ತದೆ. ಸರ್ವೇಂದ್ರಿಯದಲ್ಲೂ ಜ್ಞಾನದ ಆನಂದ ತುಂಬುತ್ತದೆ. ಎಲ್ಲಕ್ಕಿಂತ",
  "14.12": "ಲೋಭಃ ಪ್ರವೃತ್ತಿಃ ಆರಂಭಃ ಕರ್ಮಣಾಮ್‌ ಅಶಮಃ ಸ್ಪ ಎಹಾ।\n\nರಜಸಿ ಏತಾನಿ. ಜಾಯಂತೇ ವಿವೃದ್ಧೇ ಭರತರ್ಷಭ - ಓ ಭರತರ್ಷಭಾ, ರಜೋಗುಣ ಬಲಗೊಂಡಾಗ\nಕಂಡುಬರುವ ಅಂಶಗಳು ಇವು: ಜಿಪುಣತನ, ಹುಚ್ಚುಹುರುಪು, ಕಾಯಕಗಳಲ್ಲಿ ತೊಡಗುವುದು, ನೆಮ್ಮದಿಗೇಡು\nಮತ್ತು ತೀರದ ಬಯಕೆ.\n\nರಜೋಗುಣ ಜಾಗೃತವಾದಾಗ ನಮ್ಮಲ್ಲಿ ಮೊದಲು ಕಾಣಿಸಿಕೊಳ್ಳುವುದು ಲೋಭತನ. ಯಾವ ರೀತಿ ದುಡ್ಡು\nಮಾಡುವುದು ಎನ್ನುವ ಯೋಚನೆ; ಇನ್ನೊಬ್ಬರಿಗೆ ಒಂದು ಪುಡಿಗಾಸನ್ನೂ ಕೊಡದ ಜಿಪುಣತನ, ಇತ್ಯಾದಿ.\nಉದಾಹರಣೆಗೆ ಕೆಲವರು ತಮ್ಮ ಮನೆ ಸಮಾರಂಭಕ್ಕೆ ಲಕ್ಷಾಂತರ ಖರ್ಚು ಮಾಡುತ್ತಾರೆ. ಆದರೆ ಯಾರೋ\nಹೊಟ್ಟೆಗೆ ಹಿಟ್ಟಿಲ್ಲದ ವ್ಯಕ್ತಿ ಬಂದು ಕೇಳಿದರೆ ಇವರಿಂದ ಅವರಿಗೆ ಒಂದು ಪೈಸೆ ದಾನ ಕೂಡಾ ಸಿಗದು. ಇದು\nಲೋಭತನ. ಇಂತಹ ಲೋಭಿಗಳ ಬಗ್ಗೆ ನೀತಿ ಶತಕದಲ್ಲಿ ಭವಭೂತಿ ಹೀಗೆ ಹೇಳಿದ್ದಾನೆ:\n\nದಾನಂ ಭೋಗೋ ನಾಶಃ ತಿಸ್ರೋ ಭವಂತಿ ಗತಯೋ ವಿತ್ತಸ್ಯ|\n\nಯೋನ ದದಾತಿ ನಭುಂಕೇ ತಸ್ಯ ತೃತೀಯಾ ಗತಿರ್ಭವತಿ।॥|೧೫೮॥\nದುಡ್ಡಿಗೆ ಮೂರು ರೂಪದ ವಿನಿಯೋಗ: ದಾನ, ಭೋಗ, ನಾಶ. ಲೋಭಿಗಳು ತಮ್ಮಲ್ಲಿರುವ ಹಣವನ್ನು\nಇನ್ನೊಬ್ಬ ರಿಗೆ ದಾನ ಮಾಡುವುದಿಲ್ಲ, ತಾವೂ ತಿನ್ನುವುದಿಲ್ಲ, ಕೊನೆಗೆ ಅದು ನರಿ-ನಾಯಿ ಪಾಲಾಗಿ\nನಾಶವಾಗುತ್ತದೆ. ಇದು ರಜೋಗುಣದ ಪ್ರಭಾವದಿಂದಾಗುವ ಪರಿಣಾಮ. ರಜೋಗುಣದ\nಪ್ರಭಾವಕ್ಕೊಳಗಾದಾಗ ವ್ಯಕ್ತಿ ಸದಾ ಯಾವುದ್ಯಾವುದೋ ಪ್ರವೃತ್ತಿಯನ್ನು ಮಾಡ ಬಯಸುತ್ತಾನೆ. ದುಡ್ಡು\nಮಾಡುವುದಕ್ಕಾಗಿ ಬಗೆಬಗೆಯ ವ್ಯವಹಾರಗಳು; ಎಷ್ಟು ತೊಡಗಿಸಿಕೊಂಡರೂ ಅಲ್ಲಿ ಅತೃಪ್ತಿ; ತಾನು ಮಾಡುವ\nವ್ಯವಹಾರದಲ್ಲಿ ದೇವರು ತನಗೆ ಹೊಟ್ಟೆ ಬಟ್ಟೆಗಾಗುವಷ್ಟು ಕೊಟ್ಟರೂ ಕೂಡಾ ಅಲ್ಲಿ ತೃಪ್ತಿ ಇಲ್ಲದೇ ಇರುವುದು;\nತನಗೆ ಬರುತ್ತಿರುವ ಸಂಬಳದಲ್ಲಿ ತಾನು ಸುಖವಾಗಿ ಬದುಕಲು ಸಾಧ್ಯವಾದರೂ ಕೂಡಾ, ಅದು ಪಕ್ಕದ\nಮನೆಯವರ ಸಂಬಳಕ್ಕಿಂತ ಕಡಿಮೆ ಎಂದು ಕೊರಗುವುದು ಇತ್ಯಾದಿ. ಇಂತವರ ನಿತ್ಯ ಮಂತ್ರ “ಬೇಕು-ಬೇಕು”.\nಸತ್ವಗುಣವನ್ನು ತುಳಿದು ರಜೋಗುಣ ತಲೆಯೆತ್ತಿ ನಿಂತಾಗ ಈ ಎಲ್ಲಾ ಲಕ್ಷಣಗಳು ಕಾಣಿಸಿಕೊಳ್ಳುತ್ತವೆ.\nಇಲ್ಲಿ ವ್ಯಾಸರು “ಭರತರ್ಷಭ' ಎನ್ನು ವ ವಿಶೇಷಣವನ್ನು ಬಳಸಿದ್ದಾರೆ. ರಜೋಗುಣದಿಂದ ಪಾರಾಗಲು ನಾವು\nಭರತರ್ಷಭರಾಗಬೇಕು. ಐತರೇಯ ಬ್ರಾಹ್ಮಣದಲ್ಲಿ 'ವಾಯರ್ವಾವ ಭರತಃ ಎನ್ನುವ ಒಂದು ಮಾತಿದೆ. ಸದಾ\nಭಗವಂತನಲ್ಲಿ ನಿರತನಾದ ವಾಯುದೇವರಿಗೆ 'ಭರತ' ಎಂದು ಹೆಸರು. ಪ್ರಾಣದೇವರಲ್ಲಿ ಶರಣಾಗತಿ ನಮ್ಮನ್ನು\nರಜೋಗುಣದಿಂದ ಪಾರುಮಾಡಬಲ್ಲದು.\n",
  "14.13": "ಅಪ್ರಕಾಶಃ ಅಪ್ರವೃತ್ತಿಃ ಚ ಪ್ರಮಾದಃ ಮೋಹಃ ಏವ ಚ ।\nತಮಸಿ ಏತಾನಿ ಜಾಯಂತೇ ವಿವೃದ್ಧೇ ಕುರುನಂದನ - ಓ ಕುರುನಂದನಾ, ತಮಸ್ಸು ಬಲಗೊಂಡಾಗ\nಕಂಡುಬರುವ ಅಂಶಗಳು ಇವು: ಅಂಧಕಾರ, ಹುರುಪುಗೇಡು, ಎಚ್ಚರಗೇಡು ಮತ್ತು ತಪ್ಪರಿವು.\n\nತಮೋಗುಣ ಜಾಗೃತವಾದಾಗ ಒಳಗೂ ಹೊರಗೂ ಎಲ್ಲವೂ ಕತ್ತಲು. ಯಾವಾಗಲೂ ನಿದ್ದೆ ಮಾಡುವುದು, ತಪ್ಪು\nಮಾಡುವುದು, ಅಜ್ಞಾನದಲ್ಲಿ ಬದುಕುವುದು- ತಮೋಗುಣದ ಪ್ರಭಾವದಿಂದ. ಮುಂಜಾನೆ ಸೂರ್ಯ ಮೂಡುವ\nಮುಂಚೆ ಏಳಲು ತಮೋಗುಣ ಬಿಡುವುದಿಲ್ಲ. ಸದಾ ನಿದ್ದೆಮಾಡುವಂತೆ ಈ ಗುಣ ನಮ್ಮನ್ನು ಪ್ರೇರೇಪಿಸುತ್ತದೆ. ಈ\nಗುಣ ಸದಾ ಕತ್ತಲೆಯನ್ನು ಬಯಸುವಂತೆ ಮಾಡುತ್ತದೆ. ಇದರ ಪ್ರಭಾವದಿಂದ ಪಾರಾಗಲು ನಾವು\nಕುರುನಂದನರಾಗಬೇಕು. ನಮ್ಮನ್ನು ನಾವು ಯಾವುದೋ ಒಂದು ಕೆಲಸದಲ್ಲಿ ತೊಡಗಿಸಿಕೊಂಡು ಅದನ್ನು ರೂಢಿ\nಮಾಡಿಕೊಳ್ಳಬೇಕು. ಉದಾಹರಣೆಗೆ: ಮುಂಜಾನೆ ಸೂರ್ಯೋದಯವಾಗುವ ಮುಂಚೆ ಏಳುವ ಅಭ್ಯಾಸ\nಮಾಡಿಕೊಳ್ಳುವುದು. ಹೀಗೆ ರೂಢಿ ಮಾಡಿಕೊಂಡಾಗ ಮನಸ್ಸು ಅದನ್ನು ಬಿಡಲು ಕೇಳುವುದಿಲ್ಲ.\n\nನಮ್ಮಲ್ಲಿ ಕೆಲವರು ಹೇಳುವುದಿದೆ. “ಅಧ್ಯಾತ್ಮ ಚಿಂತನೆ ಮಾಡಲು ನನ್ನಲ್ಲಿ ಸಮಯವಿಲ್ಲ” ಎಂದು. ಆದರೆ ಹೀಗೆ\nಹೇಳುವವರಲ್ಲಿ ಹೆಚ್ಚಿನವರು ತಮ್ಮ ರಜಾ ದಿನಗಳಲ್ಲಿ, ಬಿಡುವಿನ ಕಾಲದಲ್ಲಿ - ಮುಂಜಾನೆಯಿಂದ ಸಂಜೆಯ ತನಕ\nಸೋಮಾರಿಯಾಗಿ ನಿದ್ದೆ ಮಾಡುತ್ತಾ ಕಾಲಹರಣ ಮಾಡುತ್ತಿರುತ್ತಾರೆ! ಹೀಗೆ ನಮಗರಿವಿಲ್ಲದಂತೆ ನಮ್ಮನ್ನು\nತಮೋಗುಣ ಆಕ್ರಮಿಸಿ ನಿಯಂತ್ರಿಸುತ್ತಿರುತ್ತದೆ. ನಾವು ಸೋಮಾರಿಯಾಗದೆ ಯಾವುದಾದರೂ ಕರ್ತವ್ಯದಲ್ಲಿ\nನಮ್ಮನ್ನು ತೊಡಗಿಸಿಕೊಳ್ಳುವುದರಿಂದ ತಮೋಗುಣದ ಪ್ರಭಾವದಿಂದ ಪಾರಾಗಬಹುದು.",
  "14.14": "ಯದಾ ಸತ್ವೇ ಪ್ರವೃದ್ಧೇ ತು ಪ್ರಳಯಮ್‌ ಯಾತಿ ದೇಹಭೃತ್‌ |\nತದಾ ಉತ್ತಮವಿದಾಮ್‌ ಲೋಕಾನ್‌ ಅಮಲಾನ್‌ ಪ್ರತಿಪದ್ಯ ತೇ -ಸತ್ವಗುಣ ಬಲಗೊಂಡಾಗ ಜೀವಿ\nಸಾವನ್ನಪ್ಪಿದರೆ, ಹಿರಿದಾದ ತತ್ವವನ್ನು- ಬಲ್ಲವರ ಕುಲದಲ್ಲಿ, ದೋಷವಿರದ ದೇಹವನ್ನು ಪಡೆಯುತ್ತಾನೆ.\n\nನಮಗೆ ತಿಳಿದಂತೆ ಜೀವ ದೇಹವನ್ನು ಬಿಟ್ಟು ಹೊರ ಹೋಗುವ ಕೊನೆಯ ಕ್ಷಣ ಆ ಜೀವದ ಮುಂದಿನ ನಡೆಯನ್ನು\nನಿರ್ಧರಿಸುತ್ತದೆ. ಅಂತ್ಯಕಾಲದಲ್ಲಿ ಸಾತ್ವಿಕವಾದ ಚಿಂತನೆಯೊಂದಿಗೆ, ಸತ್ವದ ಪ್ರಭಾವದಲ್ಲಿ ಪ್ರಾಣ ಬಿಡಲು\nಸಾಧ್ಯವಾದರೆ, ಮುಂದಿನ ಜನ್ಮದಲ್ಲಿ ಯಾವುದೇ ದೋಷವಿಲ್ಲದ ಮನುಷ್ಯರಾಗಿ ಜ್ಞಾನಿಗಳ ಸಮುದಾಯದಲ್ಲಿ\nಹುಟ್ಟುತ್ತೇವೆ. ಅಲ್ಲಿ ಜ್ಞಾನಿಗಳ ನಡುವೆ ಇದ್ದು, ಜ್ಞಾನವನ್ನು ಬೆಳೆಸಿಕೊಂಡು ಮತ್ತೆ ಜ್ಞಾನ ಮಾರ್ಗದಲ್ಲಿ\nಎತ್ತರಕ್ಕೇರಲು ಸಾಧ್ಯವಾಗುತ್ತದೆ. ಜೀವಮಾನದಲ್ಲಿ ನಾವು ಸತ್ವಕ್ಕೆ ಒತ್ತು ಕೊಟ್ಟು ಬದುಕಿದರೆ ಮಾತ್ರ\n\nಸಾಯುವಾಗ ಸತ್ವದ ಅಧಿಷ್ಠಾನದಲ್ಲಿ ಸಾಯಲು ಸಾಧ್ಯವಾಗಬಹುದು. ಇದನ್ನು ಬಿಟ್ಟು “ಸಾಯುವಾಗ ಸಾತ್ವಿಕ\nಚಿಂತನೆ ಬಗ್ಗೆ ಯೋಚಿಸೋಣ” ಎಂದು ಬದುಕಿದರೆ, ಸತ್ವದ ಪ್ರಭಾವದಲ್ಲಿ ಸಾಯುವುದು ಅಸಾಧ್ಯ.\n",
  "14.15": "ರಜಸಿ ಪ್ರಳಯಮ್‌ ಗತ್ವಾ ಕರ್ಮ ಸಂಗಿಷು ಜಾಯತೇ ।\nತಥಾ ಪ್ರಲೀನಃ ತಮಸಿ ಮೂಢ ಯೋನಿಷು ಜಾಯತೇ -ರಜೋಗುಣದಲ್ಲಿ ಸಾವನ್ನಪ್ಪಿದರೆ ಕರ್ಮಕ್ಕೆ\nಅಂಟಿಕೊಂಡವರಲ್ಲಿ ಹುಟ್ಟುತ್ತಾನೆ. ತಮೋಗುಣದಲ್ಲಿ ಸತ್ತವನು ತಿಳಿವಿರದ ಹೀನಯೋನಿಗಳಲ್ಲಿ ಹುಟ್ಟುತ್ತಾನೆ.\n\nಜ್ಞಾನಕ್ಕೆ ಪೂರಕವಲ್ಲದ ಕರ್ಮಾನುಷ್ಠಾನ ಮಾಡುತ್ತಾ ರಜೋಗುಣದ ಪ್ರಭಾವದಲ್ಲಿ ದುಡ್ಡು-ದುಡ್ಡು ಎಂದು ಬದುಕಿ,\nಅದೇ ಪ್ರಭಾವದಲ್ಲಿ ಸತ್ತರೆ-ಆಗ ಮುಂದಿನ ಜನ್ಮದಲ್ಲಿ ಕರ್ಮಕ್ಕೆ ಅಂಟಿಕೊಂಡು ಹುಟ್ಟಬೇಕಾಗುತ್ತದೆ. ಇನ್ನು\nತಮೋಗುಣದ ಪ್ರಭಾವದಲ್ಲಿ ಬದುಕಿ ಸತ್ತರೆ ಮುಂದಿನ ಜನ್ಮದಲ್ಲಿ ಹೀನಯೋನಿಯಲ್ಲಿ ಹುಟ್ಟಬೇಕಾಗುತ್ತದೆ. ಇಲ್ಲಿ\n“ಹೀನಯೋನಿ' ಅಂದರೆ ಮನುಷ್ಯ ಕೂಡಾ ಆಗಬಹುದು. ಯಾವುದೇ ಸಂಸ್ಕಾರವಿಲ್ಲದ, ಸ್ವಚ್ಛತೆ ಇಲ್ಲದ,\nಜ್ಞಾನವಿಲ್ಲದ, ಕೇವಲ ಮನುಷ್ಯ ಆಕಾರವನ್ನು ಪಡೆದು, ಮನುಷ್ಯತ್ವದ ಲವಲೇಷವಿಲ್ಲದೆ ಮನುಷ್ಯರಾಗಿ\nಬದುಕುವುದೂ ಕೂಡಾ ಹೀನಯೋನಿ ಜನನ. ಇದಕ್ಕಿಂತ ಪ್ರಾಣಿ ಜನ್ಮ ಎಷ್ಟೊ ೀ ಮೇಲು. ಇದು ತಮೋಗುಣದಲ್ಲಿ\nಸತ್ತಾಗ ಆಗುವ ಪರಿಣಾಮ. [ಸಾಯುವ ಕೊನೇ ಕ್ಷಣದಲ್ಲಿ ರಜಸ್ಸು ಮತ್ತು ತಮಸ್ಸಿನ ಪ್ರಭಾವದಿಂದ ಸತ್ತರೆ, ಅದು\nನಮ್ಮ ಮುಂದಿನ ಜನ್ಮದ ಮೇಲೆ ಹೇಗೆ ಪರಿಣಾಮ ಬೀರುತ್ತದೆ ಎನ್ನುವುದನ್ನು-ಘಜೇಂದ್ರನಾಗಿ ಹುಟ್ಟಿದ\nಇಂದ್ರದ್ಯುಮ್ನ ಮತ್ತು ಜಿಂಕೆಯಾಗಿ ಹುಟ್ಟಿದ ಭರತ ಚಕ್ರವರ್ತಿಯ ಕಥೆಯಿಂದ ನಾವು ತಿಳಿಯಬಹುದು.\nಪುನರ್ಜನ್ಮದ ಬಗ್ಗೆ ಇತ್ತೀಚಿನ ಸಂಶೋಧನೆ ಬಗ್ಗೆ ತಿಳಿಯಲು (1877 to 1920) ಅವರ ಪುಸ್ತಕಗಳು\nಹಾಗೂ ಅವರ ಮೇಲಿನ ಸಂಶೋಧನೆಯ ವಿವರಗಳನ್ನು ನೋಡಿ ].\n",
  "14.16": "ಕರ್ಮಣಃ ಸುಕೃತಸ್ಯ ಆಹುಃ ಸಾತ್ತ್ವಿಕಮ್‌ ನಿರ್ಮಲಮ್‌ ಫಲಮ್‌ ।\n\nರಜಸಃ ತು ಫಲಮ್‌ ದುಃಖಮ್‌ ಅಜ್ಞಾನಮ್‌ ತಮಸಃ ಫಲಮ್‌ - ಒಳ್ಳೆಯ ಕಜ್ಜದಿಂದ ದುಗುಡವಿರದ ಸಾತ್ವಿಕ\nಫಲ ಎನ್ನುತ್ತಾರೆ ತಿಳಿದವರು. ರಾಜಸವಾದ ಕಜ್ಜದಿಂದ ದುಃಖ ಬೆರೆತ ಸುಖ. ತಿಳಿಗೇಡಿತನವೇ ತಮೋಗುಣದ\nಕಜ್ಜದ ಫಲ.\n\nಜೀವನದುದ್ದಕ್ಕೂ ಇನ್ನೊಬ್ಬರಿಗೆ ಸಹಾಯವಾಗುವಂತಹ ಕೆಲಸ ಮಾಡಿದರೆ ಅದು ಸುಕೃತ. ನಮ್ಮಲ್ಲಿ\nಸಂಪತ್ತಿದ್ದಾಗ ಅದು ನನ್ನದು-ನನ್ನದು ಎಂದು ಜಿಪುಣನಾಗಿ ಬದುಕಿದರೆ ಅದರಿಂದ ದುಃಖಭರಿತ ಜೀವನ\n\nನಮ್ಮದಾಗುತ್ತದೆ. ನಾವು ಗಳಿಸಿದ್ದನ್ನು ಇನ್ನೊಬ್ಬರ ಕಷ್ಟದಲ್ಲಿ ವಿನಿಯೋಗಿಸಿದಾಗ ಅದು ನಮ್ಮನ್ನು ಸಾತ್ವಿಕ\nಫಲದತ್ತ ಕೊಂಡೊಯ್ಯುತ್ತದೆ. ಮಧ್ವಾಚಾರ್ಯರು ಈ ವಿಚಾರಕ್ಕೆ ಒತ್ತು ಕೊಟ್ಟು ತಮ್ಮ 'ಗೀತಾತಾತ್ಪರ್ಯ'ದಲ್ಲಿ\nಹೀಗೆ ಹೇಳಿದ್ದಾರೆ: “ನಾನಾ ಜನಸ್ಯ ಶುಶ್ರೂಷಾ ಕರ್ತವ್ಯಾ ಕರವನ್ಮಿತೇ” ಕಷ್ಟದಲ್ಲಿರುವವರ ಸೇವೆ ಮಾಡುವುದು\nಮೋಕ್ಷ ಸಾಧನೆಯ ಒಂದು ಮುಖ. ನಮ್ಮಲ್ಲಿ ಕೆಲವರು ಕಷ್ಟದಲ್ಲಿರುವವರನ್ನು ಕಂಡು ಹೀಗೆ ಹೇಳುವುದಿದೆ: “ಅದು\nಅವನ ಪ್ರಾರಾಬ್ಧಕರ್ಮ, ಅದನ್ನು ಅವನು ಅನುಭವಿಸಲಿ. ಅದಕ್ಕೆ ನಾನ್ಯಾಕೆ ಚಿಂತಿಸಬೇಕು” ಎಂದು. ಈ ರೀತಿ\nಹೇಳಿದಾಗ ನಾವು ಆ ಕಷ್ಟದಲ್ಲಿರುವ ವ್ಯಕ್ತಿಯ ಒಳಗಿರುವ ಭಗವಂತನನ್ನು ತಿರಸ್ಕಾರ ಮಾಡಿದಂತಾಗುತ್ತದೆ.\nಇಂತವರಿಗೆ ಎಂದೆಂದೂ ಭಗವಂತನ ಸಾಕ್ಷಾತ್ಕಾರವಾಗುವುದಿಲ್ಲ. ನಮ್ಮ ಆಧ್ಯಾತ್ಮಿಕ ಸಾಧನೆಯಲ್ಲಿ ಜಪ-\nತಪವಷ್ಟೇ ಸಾಲದು; ಇಲ್ಲಿ ಕಷ್ಟದಲ್ಲಿರುವ ಜನರ ಸೇವೆಯೂ ಒಂದು ಪ್ರಧಾನವಾದ ಅಂಶ. ಸಾಧಕನು ತನ್ನ\nನಿತ್ಯಾನುಷ್ಠಾನಗಳ ಜತೆಗೆ ಈ ಸೇವಾಕಾರ್ಯವನ್ನು ಆಚರಿಸಬೇಕೆನ್ನುವುದು ಗೀತೆಯ ಆದೇಶವೆಂದು\nಮಧ್ವಾಚಾರ್ಯರು ಪ್ರತಿಪಾದಿಸಿದ್ದಾರೆ. ನಿನ್ನ ಮನೆಯಲ್ಲಿ ಬೆಂದ ಅನ್ನ ಎಷ್ಟು ಹಸಿದ ಜನರ ಹಸಿವನ್ನು\nತಣಿಸುತ್ತದೋ-ಅಷ್ಟು ಸುಕೃತ. ಇದಕ್ಕಾಗಿ ಹಿಂದಿನ ಕಾಲದಲ್ಲಿ ಒಂದು ಸಂಪ್ರದಾಯವಿತ್ತು. ಅಡುಗೆ ಮಾಡಿ,\nದೇವರಿಗೆ ಅದನ್ನು ಅರ್ಪಿಸಿ, ಸುಮಾರು ಹತ್ತು ನಿಮಿಷ ಹೆಬ್ಬಾಗಿಲಿನಲ್ಲಿ ಕಾದು, ನಂತರ ಊಟ ಮಾಡುವುದು.\nಏಕೆಂದರೆ ಈ ಸಮಯದಲ್ಲಿ ಯಾರಾದರೂ ಹಸಿದವರು ಮನೆಯ ಬೀದಿಯಲ್ಲಿ ಬಂದರೆ ಅವರಿಗೆ ಮೊದಲು ಊಟ\nಬಡಿಸಿ, ಆನಂತರ ಯಜಮಾನ ಊಟಮಾಡುವುದು ಆಗಿನ ಪದ್ಧತಿಯಾಗಿತ್ತು. ಇಷ್ಟೇ ಅಲ್ಲದೆ ಇದಕ್ಕೂ ಮೊದಲು\n“\"ಬಲಿಹರಣ' ಮಾಡುತ್ತಿದ್ದರು. ಮನೆಯ ಸುತ್ತಮುತ್ತಲಿನ ಪ್ರಾಣಿ-ಪಕ್ಷಿಗಳಿಗೆ ಆಹಾರ ನೀಡುವುದು “ಬಲಿಹರಣ”.\nಹೀಗೆ ಜೀವಮಾನದುದ್ದಕ್ಕೂ ಒಳ್ಳೆಯ ಕೆಲಸ ಮಾಡಿದರೆ ಅದರ ಫಲ ಸಾತ್ವಿಕವಾಗುತ್ತದೆ. ಇದರಿಂದ ಈ\nಜನ್ಮದಲ್ಲಿ ಜ್ಞಾನ ಗಳಿಸಲು ಆಗದಿದ್ದರೂ ಕೂಡಾ, ಮುಂದಿನ ಜನ್ಮದಲ್ಲಿ ಆ ಅವಕಾಶ ಒದಗಿ ಬರುತ್ತದೆ.\nಜ್ಞಾನವಿದ್ದೂ ದುಷ್ಕೃತಿಯಾಗಿ ಬದುಕಿದರೆ ಮತ್ತೆ ಹೀನಯೋನಿಯಲ್ಲಿ ಹುಟ್ಟಬೇಕಾಗುತ್ತದೆ.\n\nಹೋಮ-ಹವನ, ದಾನ-ದಕ್ಷಿಣೆ, ಬ್ರಾಹ್ಮಣಾರಾಧನೆ- ಎಲ್ಲವನ್ನೂ ಮಾಡಿ, “ತಾನು ಎಲ್ಲರಿಗಿಂತ ಮಹಾನ್‌' ಎನ್ನುವ\nಅಹಂಕಾರ ಬಂದರೆ ಅದು ರಜಸ್ಸಿ ನ ಕರ್ಮವಾಗುತ್ತದೆ. ಅದರ ಫಲ ಲೋಭ; ದುಃಖ ಬೆರೆತ ಜೀವನ. ಇದರಿಂದ\nಪುಣ್ಯ ಕರ್ಮ ಮಾಡಿಯೂ ದುಃಖ ಅನುಭವಿಸಬೇಕಾಗುತ್ತದೆ. ಅಜ್ಞಾನದಿಂದ, ಯಾರದ್ದೋ ಒತ್ತಡಕ್ಕೆ ಮಾಡುವ\nಕರ್ಮದಿಂದ ಎಂದೂ ಜ್ಞಾನ ಬೆಳೆಯುವುದಿಲ್ಲ. ತಿಳಿಗೇಡಿತನವೇ ತಮೋಗುಣದ ಕರ್ಮಫಲ.\n\nನಮ್ಮಲ್ಲಿ ಯಾವ ಗುಣ ಪೂರ್ಣವಾಗಿ ಜಾಗೃತವಾಗಿದೆ ಎಂದು ಹೇಗೆ ತಿಳಿಯುತ್ತದೆ ಎನ್ನುವುದರ ವಿವರಣೆಯನ್ನು,\nಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ಉಪಸಂಹಾರ ರೂಪದಲ್ಲಿ ಕೃಷ್ಣ ವಿವರಿಸಿದ್ದಾನೆ .",
  "14.17": "ಸತ್ತ್ವಾತ್‌ ಸಂಜಾಯತೇ ಜ್ಞಾನಮ್‌ ರಜಸಃ ಲೋಭಃ ಏವ ಚ |\nಪ್ರಮಾದ ಮೋಹೌ ತಮಸಃ ಭವತಃ ಅಜ್ಞಾನಮ್‌ ಏವ ಚ-ಸತ್ವದಿಂದ ತಿಳಿವು ತಿಳಿಯಾಗುತ್ತದೆ. ರಜಸ್ಸಿನಿಂದ\nಜಿಪುಣತನ ಬೆಳೆಯುತ್ತದೆ. ತಮಸ್ಸಿ ನಿಂದ ಮೈಮರೆವು, ಭ್ರಾಂತಿ ಮತ್ತು ತಿಳಿಗೇಡಿತನ ಉಂಟಾಗುತ್ತದೆ.\n\n“ಸತ್ತ್ವಾತ್‌ ಸಂಜಾಯತೇ ಜ್ಞಾನಮ್‌”- ಗೀತೆಯ ಈ ಸಾಲು ಬಹಳ ಮುಖ್ಯವಾದ ಸಂದೇಶವನ್ನು ಕೊಡುತ್ತದೆ.\nಯಾವಾಗ ಮನುಷ್ಯನಿಗೆ ಉಳಿದ ಎಲ್ಲಾ ಸಂಗತಿಗಳಿಗಿಂತ ಜ್ಞಾನ ಮುಖ್ಯ, ಅದಕ್ಕಾಗಿ ನಾನು ಏನನ್ನಾದರೂ\nಕಳೆದುಕೊಳ್ಳಲು ಸಿದ್ಧ ಎನ್ನುವ ದೃಢ ನಿರ್ಧಾರ ಬರುತ್ತದೋ- ಆಗ ನಾವು ನಿಸ್ಸಂದೇಹವಾಗಿ ಇದು ಸತ್ವಗುಣದ\nಪೂರ್ಣ ಜಾಗೃತಾವಸ್ಥೆ ಎಂದು ತಿಳಿಯಬಹುದು. ಇದಕ್ಕೆ ಉತ್ತಮ ಉದಾಹರಣೆ ಕಠೋಪನಿಷತ್ತಿನಲ್ಲಿ ಬರುವ\nಯಮ ಮತ್ತು ನಚಿಕೇತನ ಈ ಸಂಭಾಷಣೆ:\n\nಏತತ್ತುಲ್ಯಂ ಯದಿ ಮನ್ಯಸೇ ವರಂ ವೃಣೀಷ್ಟ ವಿತ್ತಂ ಚಿರಜೀವಿಕಾಂ ಚ |\n\nಮಹಾಭೂಮೌ ನಚಿಕೇತಸ್ತ್ವಮೇಧಿ ಕಾಮಾನಾಂ ತ್ವಾ ಕಾಮಭಾಜಂ ಕರೋಮಿ. ॥೧-೨೪ |\nಯೇ ಯೇ ಕಾಮಾ ದುರ್ಲಭಾ ಮರ್ತ್ಯಲೋಕೇ ಸರ್ವಾನ್‌ ಕಾಮಾಂಶ್ಚಂದತಃ ಪ್ರಾರ್ಥಯಸ್ವ |\nಇಮಾ ರಾಮಾಃ ಸರಥಾಃ ಸತೂರ್ಯಾ ನ ಹೀದೃಶಾ ಲಂಭನೀಯಾ ಮನುಷ್ಯಃ |\nಆಭಿರ್ಮತೃತ್ತಾಭಿಃ ಪರಿಚಾರಯಸ್ವ ನಚಿಕೇತಶೋ ಮರಣಂ ಮಾನನುಪ್ರಾಕ್ಷೇಃ॥೧-೨೫॥\n\nಇಲ್ಲಿ “ನನಗೆ ಆತ್ಮ ಜ್ಞಾನವನ್ನು ಬೋಧಿಸು\" ಎಂದು ನಚಿಕೇತ ಯಮನನ್ನು ಕೇಳಿದಾಗ: “ನೀನಿನ್ನೂ ಚಿಕ್ಕವನು, ಆ\nವಿದ್ಯೆ ಬೇಡ. ಅದಕ್ಕೆ ಬದಲಾಗಿ ನಿನ್ನನ್ನು ಭೂಮಂಡಲದ ಚಕ್ರವರ್ತಿಯನ್ನಾಗಿ ಮಾಡುತ್ತೇನೆ; ನೀನು ಬಯಸಿದ್ದು\nಸಿಗುವಂತೆ ಮಾಡುತ್ತೇನೆ; ಆಯುಷ್ಯ ಐಶ್ವರ್ಯವನ್ನು ಕೊಡುತ್ತೇನೆ\" ಎಂದು ಜವರಾಯ ನುಡಿಯುತ್ತಾನೆ. ಆಗ\nನಚಿಕೇತ ಹೀಗೆ ಹೇಳುತ್ತಾನೆ:\n\nಶ್ವೋಭಾವಾ ಮರ್ತ್ಯಸ್ಯ ಯದಂತಕೆ ತತ್‌ ಸರ್ವೇಂದ್ರಿಯಾಹಾಂ ಜರಯಂತಿ ತೇಜಃ |\n\nಅಪಿ ಸರ್ವಂ ಜೀವಿತಮಲ್ಪಮೇವ ತವೈವ ವಾಹಾಸ್ತವ ನೃತ್ಯಗೀತೇ ॥೧-೨೬॥\n\nನ ವಿತ್ತೇನ ತರ್ಪಣೀಯೋ ಮನುಷ್ಯೋ ಲಪ್ಸ್ಯಾಮಹೇ ವಿತ್ತಮದ್ರಾಕ್ಷ್ಮ ಚೇತ್ತ್ವಾ |\nಜೀವಿಷ್ಯಾಮೋ ಯಾವದೀಶಿಷ್ಯಸಿ ತ್ವಂ ವರಸ್ತು ಮೇ ವರಣೀಯಃ ಸ ಏವ ॥೧-೨೭॥\nಅಜೀರ್ಯತಾಮಮೃತಾನಾಮುಪೇತ್ಯ ಜೀರ್ಯನ್ಮರ್ತ್ಯಃ ಕ್ವಧಃಸ್ಥಃ ಪ್ರಜಾನನ್‌ |\nಅಭಿಧ್ಯಾಯನ್‌ ವರ್ಣರತಿಪ್ರಮೋದಾನ್‌ ಅತಿದೀರ್ಫೇ ಜೀವಿತೇ ಕೋ ರಮೇತ ॥೧-೨೮॥\nಯಸ್ಮಿನ್ನಿದಂ ವಿಚಿಕಿತ್ಸಂತಿ ಮೃತ್ಯೋ ಯತ್ಸಾಂಪರಾಯೇ ಮಹತಿ ಬ್ರೂಹಿ ನಸ್ತತ್‌ |\nಯೋಕ$ಯಂ ವರೋ ಗೂಢಮನುಪ್ರವಿಷ್ಟೋ ನಾನ್ಯಂ ತಸ್ಮಾನ್ನಚಿಕೇತಾ ವೃಣೀತೇ ॥೧-೨೯॥\n\n“ನೀನು ಎಷ್ಟೇ ಕೊಟ್ಟರೂ ಅದು ಅಲ್ಪ. ಎಷ್ಟೇ ಆಯುಸ್ಸು ಪಡೆದರೂ ನಾವೊಂದು ದಿನ ಸಾಯಬೇಕು. ಆದ್ದರಿಂದ\nಇದ್ಯಾವುದೂ ನನಗೆ ಬೇಡ. ನೀನು ಇಡೀ ಜಗತ್ತನ್ನು ನನಗೆ ಧಾರೆಯೆರೆದರೂ ಅದು ನನಗೆ ಬೇಡ. ನನಗೆ ಜ್ಞಾನ\nಬೇಕು. ಆ ಆತ್ಮಜ್ಞಾನವಿದ್ಯೆಯನ್ನೇ ತಿಳಿಸಿಕೊಡು\"” ಎಂದು. ಇದು ಯಾವ ಪ್ರಲೋಭನೆಗೂ ಒಳಗಾಗದ ನಿಜವಾದ\nಸತ್ವ. ಜ್ಞಾನ ಸಾಧನೆಯ ನಿಜವಾದ ಹಸಿವುಳ್ಳವರು ಎಲ್ಲವನ್ನೂ ಕಳೆದುಕೊಳ್ಳಲು ಸಿದ್ಧರಾಗಿ ಹೇಗೆ\nಜ್ಞಾನಮಾರ್ಗದಲ್ಲಿ ಸಾಗುತ್ತಾರೆ ಎನ್ನುವುದಕ್ಕೆ ಇತ್ತೀಚೆಗಿನ ಉತ್ತಮ ಉದಾಹರಣೆ- ಸ್ವಾಮಿರಾಮ್‌ (1925-1996). ಅವರ ಜೀವನ ಚರಿತ್ರೆಯನ್ನು ನಾವು ಪುಸ್ತಕದಲ್ಲಿ\nಓದಿ ತಿಳಿಯಬಹುದು. ಶಾಸ್ತ್ರ ಓದಿದರೂ ಶಾಸ್ತ್ರದ ಯಥಾರ್ಥ ಜ್ಞಾನ ಬರಬೇಕಿದ್ದರೆ ನಮ್ಮೊಳಗೆ ಸಾತ್ವಿಕತೆ\nಇರಬೇಕು. ಅ-ಕಾರ ವಾಚ್ಯನಾದ ಭಗವಂತನ ಜ್ಞಾನ ಬರುವುದು ಸತ್ವಗುಣವಿದ್ದಾಗ ಮಾತ್ರ. ಸತ್ವಗುಣ ಪೂರ್ಣ\nಜಾಗೃತವಾದಾಗ ನಮಗೆ ಯಥಾರ್ಥಜ್ಞಾನ ತಿಳಿಯುತ್ತದೆ ಮತ್ತು ಉಳಿದ ಎಲ್ಲಾ ಪ್ರಾಪಂಚಿಕ ಸಂಗತಿ ಜ್ಞಾನದ\nಮುಂದೆ ಶೂನ್ಯ ಎನ್ನುವ ಸತ್ಯ ತಿಳಿಯುತ್ತದೆ.\n“ರಜಸೋ ಲೋಭ ಏವ ಚ”- ಲೋಭ ಎನ್ನು ವುದು ರಜಸ್ಸಿ ನ ಮೀಸಲಾದ ಗುಣ(exclusive quality). ಇದನ್ನು\nಸಾತ್ವಿಕರಲ್ಲಿ ಕಾಣಲು ಸಾಧ್ಯವಿಲ್ಲ. ಯಾವುದೋ ಒಂದು ವಸ್ತುವಿನ ಬಗ್ಗೆ ಕಾಮ, ಆ ವಸ್ತು ಸಿಗದಿದ್ದಾಗ ಕ್ರೋಧ,\nಸಿಕ್ಕಿದಾಕ್ಷಣ -ಲೋಭ. ಅದನ್ನು ಉಪಯೋಗಿಸುವುದೂ ಇಲ್ಲ, ಇನ್ನೊ ಬ್ಬರಿಗೆ ಕೊಡುವುದೂ ಇಲ್ಲ. ದಾನ\nಎನ್ನುವುದು ಇವರಿಗೆ ಬಲು ದೂರ! ನಾವು ನಮ್ಮ ಹತ್ತಿರ ಏನಿದೆಯೋ ಅದನ್ನು ಹಂಚಿ ಬದುಕಬೇಕು ಎನ್ನುವುದು\nಸತ್ವ. ಇದನ್ನು ಈಶೋಪನಿಷತ್ತಿನಲ್ಲಿ ಬಹಳ ಸುಂದರವಾಗಿ ಹೇಳಿದ್ದಾರೆ:\n\nಈಶಾವಾಸ್ಯಮಿದಂ ಸರ್ವಂ ಯತ್ಕಿಂಚ ಜಗತ್ಯಾಂ ಜಗತ್‌ |\n\nತೇನ ತ್ಯಕ್ಷೇನ ಭುಂಜೀಥಾ ಮಾ ಗೃಧಃ ಕಸ್ಯಸ್ವಿದ್ಧನಂ | ೧॥\nಭಗವಂತ ಎಲ್ಲವುದಕ್ಕೂ ಸ್ವಾಮಿ. ಅವನು ಕೊಟ್ಟ ದ್ದನ್ನು ನಾವು ಅನುಭವಿಸಬೇಕು. ಇಲ್ಲದ ಸಂಪತ್ತಿಗಾಗಿ\nಆಸೆಪಡಬಾರದು. ಜಗತ್ತಿನ ಸರ್ವ ಸಂಪತ್ತಿನ ಒಡೆಯ ಆ ಭಗವಂತ. ಆದ್ದರಿಂದ ಆತ ಕೊಟ್ಟಿರುವ ಸಂಪತ್ತನ್ನು\n'ನನ್ನದು' ಎಂದುಕೊಂಡು ಲೋಭದಿಂದ ಬದುಕುವುದು ಸರಿಯಲ್ಲ. ಆದರೆ ರಜೋಗುಣದ ಬಹಳ ಮುಖ್ಯ ದೋಷ\nಈ ಲೋಭ. ಇದು ಇನ್ನೊ ಬ್ಬರ ಬಗ್ಗೆ ಸಹಾನುಭೂತಿ ಇಲ್ಲದೆ, ತಾನು ಗಳಿಸಿದ್ದನ್ನು ಇನ್ನೊಬ್ಬ ರಿಗೆ ಕೊಡದೇ,\nಕೆಲವೊಮ್ಮೆ ತಾನೂ ತಿನ್ನದೆ ಮುಚ್ಚಿಡುವಂತೆ ಮಾಡುತ್ತದೆ. ಸಾಮಾನ್ಯವಾಗಿ ಪ್ರಾಣಿಗಳಲ್ಲೂ ಇಲ್ಲದ ಕೆಟ್ಟ ಗುಣ\nಈ ಲೋಭ. ನಮ್ಮಲ್ಲಿ ಲೋಭದ ಲಕ್ಷಣವಿದ್ದರೆ ಅದು ರಜೋಗುಣದ ಜಾಗೃತಾವಸ್ಥೆ ಎನ್ನುವುದನ್ನು ನಾವು\nಅರಿಯಬೇಕು.\n“ಪ್ರಮಾದಮೋಹೌ ತಮಸೋ ಭವತೋಇಜ್ಞಾನಮೇವ ಚ”. ಹೇಗೆ ರಜೋಗುಣದಿಂದ ಲೋಭವೋ, ಹಾಗೆ\nತಮೋಗುಣದಿಂದ ಪ್ರಮಾದ ಮತ್ತು ಮೋಹ-ಅದರಿಂದ ತಿಳಿಗೇಡಿತನ... ಒಬ್ಬರನ್ನು ಅತಿಯಾಗಿ\nಹಚ್ಚಿಕೊಳ್ಳುವುದು, ಅದರಿಂದ ಅವರು ಮಾಡುವ ತಪ್ಪುಗಳನ್ನು ಕ್ಷಮಿಸುವುದು, ಅವರು ಹೇಳಿದಂತೆ\nಕುಣಿಯುವುದು, ಇತ್ಯಾದಿ. ಇದು ಎಷ್ಟು ಪ್ರಭಾವಶಾಲಿ ಎಂದರೆ- ಇದು ನಮ್ಮ ಜ್ಞಾನವನ್ನೂ ಕೂಡಾ ಮುಚ್ಚಿಸಿ,\nನಮ್ಮನ್ನು ತಪ್ಪು ದಾರಿಯಲ್ಲಿ ಕರೆದೊಯ್ಯುತ್ತದೆ. ಇದಕ್ಕೆ ಉತ್ತಮ ಉದಾಹರಣೆ ಭಾಗವತದ ಆರನೇ ಸ್ಕಂದದ\nಮೊದಲ ಅಧ್ಯಾಯದಲ್ಲಿ ಬರುವ ಅಜಾಮಿಳನ ಕಥೆ. ಈತ ಒಬ್ಬ ಸಾತ್ವಿಕ ಬ್ರಾಹ್ಮಣ. ಆತನಿಗೆ ಮದುವೆಯಾಗಿತ್ತು.\nಒಮ್ಮೆ ಪೂಜೆಗೆ ಹೂ-ತುಳಸಿ ತರಲು ಕಾಡಿಗೆ ಹೋದಾಗ ಕಂಡ ಒಂದು ದೃಶ್ಯ ಆತನ ಮನಸ್ಸಿನ ಮೇಲೆ\nಗಾಢವಾದ ಪರಿಣಾಮ ಬೀರಿತು. ತಾನು ಕಾಡಿನಲ್ಲಿ ಕಂಡ ಯುವತಿಯನ್ನು ಆತ ಮೋಹಿಸಲಾರಂಭಿಸಿದ.\nಆಕೆಗಾಗಿ ಮದ್ಯ-ಮಾಂಸಾಹಾರದಲ್ಲಿ ತೊಡಗಿದ. ಆಕೆಯ ಬಯಕೆಗಳನ್ನು ತೀರಿಸಲು ಕಳ್ಳತನ ಮಾಡಿದ.\nಸಾತ್ವಿಕನಾಗಿದ್ದ ಒಬ್ಬ ವಿಪ್ರ-ಪೂರ್ಣ ತಾಮಸನಾದ. ಈ ಕಥೆಯನ್ನು ಮನಃಶಾಸ್ತ್ರೀಯವಾಗಿ ನೋಡಿದರೆ- ಈ\nರೀತಿ ಘಟನೆ ಏಕೆ ನಡೆಯಿತು ಎನ್ನುವುದು ತಿಳಿಯುತ್ತದೆ. ಅಜಾಮಿಳ ಮದುವೆಯಾಗಿದ್ದ, ಆದರೆ ಆತನ\nಮನೆಯಲ್ಲಿ ಮಡಿ-ಮೈಲಿಗೆ ಎನ್ನುವ ಅನೇಕ ಕರ್ಮಾಚರಣೆಯಿಂದಾಗಿ ಆತ ತನ್ನಲ್ಲಿನ ಅಂತರಂಗದ\n\nಬಯಕೆಯನ್ನು ಬಲವಂತವಾಗಿ ನಿಗ್ರಹಿಸಿದ್ದ. ನಾವು ನಮ್ಮ ಬಯಕೆಯನ್ನು ಬಲವಂತವಾಗಿ ತಡೆಹಿಡಿದರೆ ಅದು\nಒಂದಲ್ಲ ಒಂದು ದಿನ ಸ್ಪೋಟವಾಗಿ ಹೊರಬರುತ್ತದೆ. ಈ ಕಾರಣದಿಂದಾಗಿ ಶಾಸ್ತ್ರಕಾರರು ಹೇಳುವಂತೆ\n“ಅಧ್ಯಾತ್ಮ ಸಾಧನೆ ಮಾಡುವ ಮೊದಲು ನಿನಗೆ ಸಾಂಸಾರಿಕ ಸುಖದ ಮೋಹವಿದ್ದರೆ ಅದನ್ನು ಅನುಭವಿಸು,\nಅದರ ನಿಸ್ಸಾರವನ್ನು ಅರಿ, ಆಗ ಸಾಧನೆ ಸುಲಭ” ಎಂದು. ಅಜಾಮಿಳ ಶಾಸ್ತ್ರ ಓದಿದ್ದ, ಆದರೂ ಆತ ಮೋಹಕ್ಕೆ\nಬಲಿಯಾದ. ಅದರಿಂದ ಆತನ ಎಲ್ಲಾ ಜ್ಞಾನವೂ ಮರೆಯಾಯಿತು. ತಮೋಗುಣ ಆತನಲ್ಲಿ ಮಾಡಬಾರದ\nತಪ್ಪನ್ನು ಮಾಡಿಸಿತು. ಇದು ತಮೋಗುಣ ನಮ್ಮಲ್ಲಿ ಪ್ರಬಲವಾದಾಗ ನಮ್ಮ ಮೇಲೆ ಆಗುವ ಪರಿಣಾಮ.\n\nಈ ಶ್ಲೋಕದಲ್ಲಿ ಕೃಷ್ಣ ನಮ್ಮಲ್ಲಿ ಯಾವ ಗುಣ ಕೆಲಸ ಮಾಡುತ್ತಿದೆ ಎನ್ನುವುದನ್ನು ಸ್ಪಷ್ಟ ರೂಪುರೇಷೆಯಿಂದ\nವಿವರಿಸಿದ. ಈ ಶ್ಲೋಕದ ಸಂಗ್ರಹ ಸಾರಾಂಶ ಇಷ್ಟು: ಜ್ಞಾನದ ತೃಷೆ ಇದ್ದರೆ ಅದು ಸಾತ್ವಿಕ ಗುಣ; ನನಗೇ ಬೇಕು\nಉಳಿದವರಿಗೆ ಸಿಗಬಾರದು ಎನ್ನುವ ಲೋಭವಿದ್ದರೆ ಅದು ರಜಸ್ಸು; ಯಾವುದೋ ಒಂದು ಭೌತಿಕ ವಸ್ತುವಿನ\nಮೇಲೆ ಅತಿಯಾದ ಮಮತೆ, ಮೋಹ ಬೆಳೆದರೆ ಅದು ತಮಸ್ಸಿನ ಕೆಲಸ.\n\nಸತ್ವ-ರಜಸ್ಸು-ತಮಸ್ಸುಗಳಿಗೆ. ಇನ್ನೊಂದು ಮುಖವಿದೆ. ಪೂಜೆಯಲ್ಲಿ ನವಶಕ್ತಿಗಳನ್ನು ಹೇಳಿದ ಮೇಲೆ\nಭಗವಂತನನ್ನು ಅನುಸಂಧಾನ ಮಾಡುವ ಮುಂಚೆ “ಸಂ ಸತ್ತ್ವಾಯ ನಮಃ -ರಂ-ರಜಸೇ ನಮಃ-ತಂ ತಮಸೇ\nನಮಃ” ಎನ್ನುವ ಒಂದು ಮಂತ್ರ ಹೇಳುತ್ತಾರೆ. ಈ ಮಂತ್ರವನ್ನು ಕೆಲವರು ಈ ರೀತಿ ಕೂಡಾ ಹೇಳುತ್ತಾರೆ: “ಸಂ\nಸತ್ತ್ವಾಯ ಶ್ರಿಯೋ ನಮಃ-ರಂ ರಜಸೇ ಭೂವೇ ನಮಃ-ತಂ ತಮಸೇ ದುರ್ಗಾಯ ನಮಃ” ಎಂದು. [ಇದು\nಮಂತ್ರವಲ್ಲ, ಮೂಲರೂಪದ ಮಂತ್ರ: “ಸಂ ಸತ್ತ್ವಾಯ ನಮಃ -ರಂ-ರಜಸೇ ನಮಃ-ತಂ ತಮಸೇ ನಮಃ” ] ಇಲ್ಲಿ\nಸಂ ಸತ್ವಾಯ ನಮಃ ಎಂದರೆ ಸತ್ವಗುಣಕ್ಕೆ ನಮಸ್ಕಾರ ಮಾಡುವುದಲ್ಲ- ಸತ್ವ ಮಾನಿನಿಯಾದ ಶ್ರೀದೇವಿಗೆ\nನಮಸ್ಕಾರ ಮಾಡುವುದು. ರಂ ರಜಸೇ ನಮಃ ಎಂದರೆ ರಜೋ ಮಾನಿನಿಯಾದ ಭೂದೇವಿಗೆ ನಮಸ್ಕಾರ. ತಂ\nತಮಸೇ ನಮಃ ಎಂದರೆ ತಮೋ ಮಾನಿನಿಯಾದ ದುರ್ಗಾ ದೇವಿಗೆ ನಮಸ್ಕಾರ. ಇವು ಲಕ್ಷ್ಮಿಯ ಮೂರು\nರೂಪಗಳು. ಲಕ್ಷ್ಮಿಯ ಮೂಲ ರೂಪಕ್ಕೆ \"ಮಹಾಲಕ್ಷ್ಮಿ' ಎನ್ನುತ್ತಾರೆ. ಈ ಮೂಲರೂಪದಿಂದ ಮೂರು ಆವೇಶ\nರೂಪಗಳು.\n\nಇಲ್ಲಿ ಸತ್ವವನ್ನು ಜಾಗೃತೆಗೊಳಿಸುವವಳು ಶ್ರೀದೇವಿ; ರಜಸ್ಸನ್ನು ಜಾಗೃತೆಗೊಳಿಸುವವಳು ಭೂದೇವಿ;\nತಮೋಗುಣವನ್ನು ಜಾಗೃತೆಗೊಳಿಸುವವಳು ತಮೋಮಾನಿನಿಯಾದ ದುರ್ಗಾದೇವಿ. “ಸತ್ತ್ವಾತ್‌ ಸಂಜಾಯತೇ\nಜ್ಞಾನಮ್‌”- ಅಂದರೆ: ಸತ್ವಗುಣದ ಅಭಿಮಾನಿನಿಯಾದ ಲಕ್ಷಿ ಕ ಜ್ಞಾನಪ್ರದಳು ಎಂದರ್ಥ. ನಾರಾಯಣನ ಜ್ಞಾನ\nಬರಬೇಕಾದರೆ ಶ್ರೀದೇವಿಯ ಅನುಗ್ರಹಬೇಕು. 'ಶ್ರೀ' ಸಂಪತ್ತನ್ನು ಕೊಡುತ್ತಾಳೆ ಎನ್ನುವ ವಿಚಾರ ಎಲ್ಲರಿಗೂ\nಗೊತ್ತು. ಆದರೆ ಜ್ಞಾನವೆಂಬ ಮಹಾ ಸಂಪತ್ತನ್ನು ಕೊಡುವವಳು ಶ್ರೀದೇವಿ ಎನ್ನುವ ವಿಚಾರ ಹೆಚ್ಚಿನವರಿಗೆ\nತಿಳಿದಿಲ್ಲ. ದುಡ್ಡು ಸಂಪತ್ತು ಹೌದು, ಆದರೆ ಜ್ಞಾನ ಮಹಾಸಂಪತ್ತು-ಅದನ್ನು ಕೊಡುವವಳು 'ಶ್ರೀ'. ನಮ್ಮೊಳಗೆ\nಜ್ಞಾನ ಜಾಗೃತವಾಗಬೇಕಾದರೆ ಮೊದಲು ತಾಯಿಯ `ಶ್ರೀ ರೂಪವನ್ನು ಉಪಾಸನೆ ಮಾಡಬೇಕು. ಭಗವಂತನ\nಜ್ಞಾನವನ್ನು ಕರುಣಿಸು ಎಂದು ಆಕೆಯನ್ನು ಬೇಡಬೇಕು.\n\nಶಾಸ್ತ್ರಕಾರರು... ಹೇಳುವಂತೆ... ಮನಸ್ಸು. ಭಗವಂತನತ್ತ ಹರಿಯುವುದಕ್ಕೆ. ಮೊದಲು ನಾವು\nಮನೋಂಇಭಿಮಾನಿಯನ್ನು ಪ್ರಾರ್ಥಿಸಬೇಕು. ಶಿವ.ಮನೋ$ಭಿಮಾನಿ ದೇವತೆ. \n\nಜ್ಞಾನ ಬೇಕು ಅನ್ನುವವರ ಮನಸ್ಸಿನ ತಮೋಗುಣವನ್ನು, ಕತ್ತಲೆಯನ್ನು ಓಡಿಸಿ ಬೆಳಕು ತುಂಬುವವರು ಶಿವ-\nಪಾರ್ವತಿಯರು. ಈ ಕಾರಣಕ್ಕಾಗಿ ಜ್ಞಾನಕ್ಕೋಸ್ಕರ ಮೊದಲು ನಾವು ಪ್ರಾರ್ಥನೆ ಮಾಡಬೇಕಾಗಿರುವುದು\nಶಿವತತ್ವವನ್ನು. ಶಿವ ಜ್ಞಾನ ಕೊಟ್ಟ ಮೇಲೆ ಅದು ಚಿತ್ತದಲ್ಲಿ ಸ್ಮರಣಶಕ್ತಿಯಾಗಿ ಉಳಿಯಲು ನಾವು\nಪ್ರಾರ್ಥಿಸಬೇಕಾಗಿರುವುದು ಪ್ರಾಣಶಕ್ತಿಯನ್ನು (ಬ್ರಹ್ಮ-ವಾಯು, ಸರಸ್ವತಿ-ಭಾರತಿ)ಘ. ನಮಗೆ ಬಂದ ಜ್ಞಾನ\nಮರೆಯಾಗದಂತೇ(ಸ್ಥಿರವಾಗುವಂತೆ) ಮಾಡುವ ಪ್ರಮುಖ ಶಕ್ತಿ ಪ್ರಾಣಶಕ್ತಿ (ಆಂಜನೇಯ). ಈ ರೀತಿ\nಸ್ಥಿರವಾದದ್ದು ಮತ್ತೆ ಎತ್ತರಕ್ಕೆ ಹೋಗಿ ಭಗವಂತನನ್ನು ಮುಟ್ಟುವಂತೆ ಮಾಡುವವಳು-ಸದಾ ಭಗವಂತನ\nಜೊತೆಗಿರುವ ಲಕ್ಷ್ಮೀದೇವಿ. ಇಂತಹ ಲಕ್ಷ್ಮಿ ತನ್ನ ಎಲ್ಲಾ ರೂಪದಲ್ಲಿ ಅರಿವನ್ನು ಕೊಡುವುದಿಲ್ಲ. ಆಕೆ ತನ್ನ\nಶ್ರೀರೂಪದಲ್ಲಿ ಜ್ಞಾನರೂಪವಾದ ಸಂಪತ್ತನ್ನು ಕರುಣಿಸುತ್ತಾಳೆ. 'ಶ್ರೀ' ಮಹಾಲಕ್ಷ್ಮಿಯ ಅವತಾರಗಳಲ್ಲಿ ಒಂದು.\nಸತ್ವವನ್ನು ನಿಯಮನ ಮಾಡಿ ಜಗತ್ತಿನ ರಕ್ಷಣೆಗೆ ವಿಷ್ಣುವಿನ ಜೊತೆಗೆ ಪಣತೊಟ್ಟು ನಿಂತ ರೂಪವಿದು. ಆದ್ದರಿಂದ\nಜ್ಞಾನ ಮಾರ್ಗದಲ್ಲಿ ಸಾಗುವವರಿಗೆ ಮುಖ್ಯವಾದುದು ಲಕ್ಷ್ಮಿಯ ಶ್ರೀ ನಾಮಕ ಅನುಗ್ರಹ.\nಇಲ್ಲಿ ಸಾವು ಶಿವ, ಪ್ರಾಣದೇವರು ಮತ್ತು ಶ್ರೀದೇವಿ ಅನುಗ್ರಹದಿಂದ ಜ್ಞಾನಮಾರ್ಗದಲ್ಲಿ ಮುನ್ನೆಡೆದು\nಭಗವಂತನನ್ನು ಸೇರಬಹುದು ಎನ್ನುವುದನ್ನು ವಿಶ್ಲೇಷಿಸಿದೆವು. ಮುಂದೆ ಭೂತತ್ವದ ಬಗ್ಗೆ ವಿಶ್ಲೇಷಿಸುವ ಮೊದಲು\nಶಾಂತಿಮಂತ್ರ ಮತ್ತು ಗಣಪತಿಯ ಪ್ರಾರ್ಥನೆಯ ಮಹತ್ವವನ್ನು ಸಂಕ್ಷಿಪ್ತವಾಗಿ ಇಲ್ಲಿ ವಿಶ್ಲೇಷಿಸೋಣ. ಯಾವುದೇ\nಶಾಸ್ತ್ರವನ್ನು ಓದುವ ಮೊದಲು ಓಂ ಶಾಂತಿಃ ಶಾಂತಿಃ ಶಾಂತಿಃ\" ಎಂದು ಶಾಂತಿ ಮಂತ್ರ ಪಡಿಸುತ್ತೇವೆ.\nಜ್ಞಾನಾನಂದಗಳ ಪರಾಕಾಷ್ಠೆಯಾದ ಭಗವಂತನೇ, ನನ್ನನ್ನು ಜ್ಞಾನಾನಂದಗಳ(ಶಾಂತಿ) ದಾರಿಯಲ್ಲಿ ನೆಡೆಸು\nಎನ್ನುವುದು ಈ ಶಾಂತಿ ಮಂತ್ರದ ಅರ್ಥ. ಇದೇ ರೀತಿ, ಪ್ರತೀ ಪೂಜೆಯಲ್ಲಿ ಮೊದಲು ಗಣಪತಿ ಪ್ರಾರ್ಥನೆ\nಮಾಡುತ್ತೇವೆ. ಏಕೆಂದರೆ ಶಿವ-ಪಾರ್ವತಿ ಪುತ್ರ ಗಣಪತಿ ಆಕಾಶದ ದೇವತೆ. ಈ ಆಕಾಶ ಭಗವಂತನ\nನಾಭಿಯಿಂದ ಸೃಷ್ಟಿಯಾಗಿದೆ. ಆದ್ದರಿಂದ ಗಣಪತಿ ನಮ್ಮ ನಾಭಿ ದೇವತೆ.\n\nನಾಭ್ಯ ಆಸೀದಂತರಿಕ್ಷಂ ಶೀಷ್ನೊ ಧ್ಯೋ ಸಮವರ್ತತ\n\nಪದ್ಭ್ಯಾಂ ಭೂಮೀರ್‌ ದಿಶ ಶ್ರೋತ್ರಾತ್‌ ತತಾ ಲೋಕಾ ಅಕಲ್ಪಯನ್‌\nನಮ್ಮ ನಾಭಿಯ ಸಮೀಪ ಇರುವ ಮೂರು ಚಕ್ರಗಳು-ಮೂಲಾಧಾರ, ಸ್ವಾದಿಷ್ಟಾನ ಹಾಗೂ ಮಣಿಪುರ.\nನಾಭಿಯಿಂದ ಮೇಲಕ್ಕೆ ಹೃತ್ಕಮಲದಲ್ಲಿ ನಿಜವಾದ ಸಾಧನೆಯ ಅನಾಹತ ಚಕ್ರವಿದೆ. ಮೂಲಾಧಾರ,\nಸ್ವಾದಿಷ್ಟಾನ ಹಾಗೂ ಮಣಿಪುರ ಚಕ್ರಗಳನ್ನು ಮೀರಿ ಹೃದಯವನ್ನು ಪ್ರವೇಶಿಸಬೇಕಾದರೆ ನಾಭಿಯ ಬಾಗಿಲನ್ನು\nಗಣಪತಿ ತೆರೆಯಬೇಕು. ಅದಕ್ಕಾಗಿ ನಾವು ಗಣಪತಿಯಲ್ಲಿ ಮೊತ್ತಮೊದಲಿಗೆ ಪ್ರಾರ್ಥನೆ ಮಾಡುತ್ತೇವೆ. ಪ್ರತೀ\nಯಜ್ಞದ ಮೊದಲು ಗಣಪತಿ ಮಂಡಲ ಬರೆದು ಪೂಜಿಸಿ, ಆನಂತರ ಯಜ್ಞ ಪ್ರಾರಂಭಿಸುತ್ತಾರೆ. ಗಣಪತಿ ನಾಭಿಯ\nಬಾಗಿಲನ್ನು ತೆರೆದಾಗ ಹೃತ್ಯಮಲ ತಾನೇ-ತಾನಾಗಿ ತೆರೆದುಕೊಳ್ಳುತ್ತದೆ. ಈ ಸ್ಥಿತಿಯನ್ನು 'ವೃಷಾಹ' ಎನ್ನುತ್ತಾರೆ.\nಭಗವಂತ ಈ ಸ್ಥಿತಿಯಲ್ಲಿ ನಮ್ಮ ಪೂಜೆಯನ್ನು ವೃಷಾಹೀಯಾಗಿ ಸ್ವೀಕರಿಸುತ್ತಾನೆ. ಇಂತಹ ಭಗವಂತನನ್ನು\n“ವೃಷಾಹೀ' ಎಂದೂ ಕರೆಯುತ್ತಾರೆ.\n\n“ರಜಸೋ ಲೋಭ ಏವ ಚ”- ರಜಸ್ಸು ಎಂದರೆ ರಜೋಗುಣದ ಅಭಿಮಾನಿನಿಯಾದ ಭೂದೇವಿ”. ಇಲ್ಲಿ ಭೂದೇವಿ\nಎಂದರೆ ಭೂಮಿಯ ನಿಯಮನ ಮಾಡುವ ಹದಿನೆಂಟನೇ ಕಕ್ಷೆಯಲ್ಲಿರುವ ದೇವತೆ ಅಲ್ಲ. ಅವಳನ್ನೂ ನಿಯಮನ\n\nಮಾಡುವ ಲಕ್ಷ್ಮಿಯ ಆವೇಶರೂಪ 'ಭೂ'. ಅದು ಸೃಷ್ಟಿಗೆ ಕಾರಣವಾದದ್ದು. ರಂಜನೆ, ಆಕರ್ಷಣೆ, ಸೆಳೆತ, ಮೋಹ -\nಇವೆಲ್ಲವೂ ರಜೋಗುಣದ ಮುಖಗಳು. ಹಾಗಾಗಿ ಒಬ್ಬರನ್ನು ಒಬ್ಬರು ಪ್ರೀತಿಸುವುಕ್ಕೆ ಮೂಲಭೂತವಾಗಿ\nಬೇಕಾಗಿರುವುದು-ರಂಜನ. ಗಂಡು-ಹೆಣ್ಣಿನ ಸೆಳೆತವೇ ಸೃಷ್ಟಿಗೆ ಕಾರಣವಾದದ್ದು. ಸೃಷ್ಟಿಗೆ ಬೇಕಾದ ಸೆಳೆತ ಕೊಟ್ಟು\nಸೃಷ್ಟಿ ಮಾಡುವ, ಅದೇ ಸೆಳೆತದಿಂದ ದಾರಿ ತಪ್ಪಿಸುವ ಅಂಶ ರಜೋಗುಣದಲ್ಲಿದೆ. ಅಂತಹ ರಜೋಗುಣದ\nಸ್ವಭಾವವನ್ನು ಕೊಡುವವಳು ಭೂದೇವಿ. ನನ್ನ ಆಸ್ತಿ, ನನ್ನ ಮನೆ, ನನ್ನ ದುಡಿಮೆ, ನನ್ನ ಹಣ, ಇತ್ಯಾದಿ ಮೋಹ\nರಜೋಗುಣದಿಂದ ಬರುವಂತಾದ್ದು.\n\n“ಪ್ರಮಾದ ಮೋಹೌ ತಮಸಃ ಭವತಃ ಅಜ್ಞಾನಮ್‌ ಏವ ಚ”- ಭೌತಿಕವಾಗಿ ನಮ್ಮನ್ನು ವಿನಾಶದತ್ತ\nಕೊಂಡೊಯ್ಯುವ-ಸಂಹಾರ ಶಕ್ತಿಯಾದ, ತಮೋಗುಣದ ಅಭಿಮಾನಿನಿ.. ದುರ್ಗೆ. ಆಕೆ ಸಂಹಾರದ ಕಡೆಗೆ\nಹೋಗುವ ಬುದ್ಧಿ ಕೊಡುತ್ತಾಳೆ. ತಪ್ಪನ್ನೇ ಸರಿ ಎಂದು ತಿಳಿದು ತಪ್ಪು ಮಾಡುವುದು, ಅದರಿಂದ ಜಾರಿ\nಬೀಳುವುದು, ವಿಪರೀತ ಜ್ಞಾನ, ಜ್ಞಾನದ ಅಭಾವ, ಇತ್ಯಾದಿ-ತಮೋಗುಣದ ಪ್ರಭಾವದಿಂದ ಬರುವಂತಾದ್ದು.\nಹೀಗೆ. ಚಿತ್ರಕೃತಿಯ ಮೂರು ಆವೇಶರೂಪಗಳಾದ ಶ್ರೀ-ಭೂ-ದುರ್ಗ, ಸತ್ವ-ರಜಸ್ಸು-ತಮಸ್ಸಿನ\nಅಭಿಮಾನಿನಿಯರಾಗಿ, ತ್ರಿಗುಣಗಳ ಮೂಲಕ ನಮ್ಮನ್ನು ಬಂಧಿಸುತ್ತಾರೆ. ಆದ್ದರಿಂದ ಚಿತ್ರಕೃತಿಯ ಚೈತನ್ಯದ\nಮೂರು ರೂಪಗಳೇ ಸತ್ವ-ರಜಸ್ಸು ಮತ್ತು ತಮಸ್ಸು. [ಏಕೆ ಇಲ್ಲಿ ಈ ಅರ್ಥವನ್ನು ಮಾಡಬೇಕು ಎನ್ನುವುದಕ್ಕೆ\nಗೀತೆಯಲ್ಲೇ ಸುಳಿವಿದೆ. ಅದನ್ನು ಮುಂದೆ ಈ ಅಧ್ಯಾಯದ ೧೯ನೇ ಶ್ಲೋಕದಲ್ಲಿ ಕಾಣಬಹುದು. ಮಹಾಲಕ್ಷ್ಮಿಯ\nಶ್ರೀ-ಭೂ-ದುರ್ಗಾ ರೂಪದ ಬಗ್ಗೆ ಇನ್ನೂ ಹೆಚ್ಚಿನ ಮಾಹಿತಿ ಬೇಕಿದ್ದರೆ ಮಹಾಭಾರತ ತಾತ್ಪರ್ಯ ನಿರ್ಣಯದ\n“ಸರ್ಗಾನುಸರ್ಗ-ಲಯ-ಪ್ರಾದುರ್ಭಾವ ನಿರ್ಣಯ”ವನ್ನು ಓದಿ].\n",
  "14.18": "ಊರ್ಧ್ವಮ್‌ ಗಚ್ಛಂತಿ ಸತ್ತ್ವಸ್ಥಾಃ ಮಧ್ಯೇ ತಿಷ್ಠಂತಿ ರಾಜಸಾಃ ।\nಜಘನ್ಯಗುಣ ವೃತ್ತಿಸ್ಥಾಃ ಅಧಃ ಗಚ್ಛಂತಿ ತಾಮಸಾಃ-ಸತ್ವದಲ್ಲಿ ನೆಲೆಗೊಂಡವರು ಎತ್ತರಕ್ಕೆರುತ್ತಾರೆ. ರಾಜಸರು\nನಡುವಿನಲ್ಲಿ ನಿಲ್ಲುತ್ತಾರೆ. \"ಕೊನೆಯ ಗುಣದ' ಪ್ರಭಾವಕ್ಕೊಳಗಾದ ತಾಮಸರು ಕೆಳಕ್ಕೆ ಕುಸಿಯುತ್ತಾರೆ.\n\nತ್ರಿಗುಣದ ಸ್ವಭಾವವನ್ನು ಹೇಳಿದ ಕೃಷ್ಣ, ಅದರ ಪರಿಣಾಮದ ಮೂರು ಮಜಲನ್ನು ಈ ಶ್ಲೋಕದಲ್ಲಿ ವಿವರಿಸಿದ್ದಾನೆ.\nಸತ್ವದಲ್ಲಿರುವವರು ಮಾನಸಿಕವಾಗಿ ಮೇಲಕ್ಕೇರುತ್ತಾರೆ. ರಜೋಗುಣದವನಿಗೆ ಯಾವ ಏಳಿಗೆಯೂ ಇಲ್ಲ.\nತಮಸ್ಸಿನಲ್ಲಿರುವವ ಮಾನಸಿಕವಾಗಿ ಅಧಃಪಾತ ಹೊಂದುತ್ತಾನೆ. ಇಲ್ಲಿ \"ಊರ್ಧ್ವ' ಎನ್ನುವ ಪದಕ್ಕೆ ವಿಶೇಷವಾದ\nಅರ್ಥವಿದೆ. ಕಠೋಪನಿಷತ್ತಿನಲ್ಲಿ ಹೇಳುವಂತೆ :\n\nಊರ್ಧ್ವಮೂಲೋ ಅವಾಕ್ಕಾಖಃ ಏಷೋ ಅಶ್ವತ್ಥಃ ಸನಾತನಃ ॥|೨-೩-೧॥\nಊರ್ಧ್ವ ಎಂದರೆ ಎಲ್ಲಕ್ಕೆಂತ ಮೇಲಿರುವ ಭಗವಂತ. ಸತ್ವದಲ್ಲಿರುವವ ಮೇಲಕ್ಕೆ ಹೋಗುವುದು ಅಂದರೆ-\nಭಗವಂತನ ಕಡೆ ಮುಖಮಾಡಿ ಚಲಿಸುವುದು. ಆತ ಮುಂದೆ ಹೋದಂತೆ ಭಗವಂತನಿಗೆ ಹತ್ತಿರವಾಗುತ್ತಾ\n\nಹೋಗುತ್ತಾನೆ. ಆದರೆ ತಮಸ್ಸಿನಲ್ಲಿರುವವ ಭಗವಂತನಿಗೆ ಬೆನ್ನು ಹಾಕಿ ಚಲಿಸುತ್ತಿರುತ್ತಾನೆ. ರಾಜಸ ಇದ್ದಲ್ಲೇ\nಅತಂತ್ರ ಸ್ಥಿತಿಯಲ್ಲಿ ಮುಂದುವರಿಯುತ್ತಾನೆ.\n\nದೇವತೆಗಳನ್ನು ಬಂಧನದಲ್ಲಿಡುವ ಶಕ್ತಿ ಶ್ರೀದೇವಿ'; ಮಾನವರನ್ನು ಬಂಧನದಲ್ಲಿಡುವ ಶಕ್ತಿ \"ಭೂದೇವಿ' ಮತ್ತು\nರಾಕ್ಷಸರನ್ನು ಬಂಧನದಲ್ಲಿಡುವ ಶಕ್ತಿ 'ದುರ್ಗಾದೇವಿ'. ಸಾತ್ವಿಕರು ಸತ್ವಮಾನಿನಿಯಾದ 'ಶ್ರೀದೇವಿಯ' ಕೃಪೆಗೆ\nಪಾತ್ರರಾಗಿ ಮೇಲಿನ ಲೋಕವನ್ನು ಪಡೆಯುತ್ತಾರೆ[ಭೂಮಿಯಿಂದ ಮೇಲೆ ಇರುವ ಆರು ಸೂಕ್ಷ್ಮ ಲೋಕಗಳು\nಮತ್ತು ಕೊನೆಗೆ ಮೋಕ್ಷ]; ರಾಜಸರು ಭೂದೇವಿಯ ಬಂಧನದಲ್ಲೇ ಮುಂದುವರಿಯುತ್ತಾರೆ[ಭೂಮಿ ಮತ್ತು\nಅಂತರಿಕ್ಷ] ಮತ್ತು ತಾಮಸರು ದುರ್ಗಾದೇವಿಯ ನಿಯಂತ್ರಣದಲ್ಲಿರುವ ತಾಮಸಲೋಕ [ಭೂಮಿಯಿಂದ\nಕೆಳಗಿರುವ ಏಳು ಸೂಕ್ಷ್ಮಲೋಕಗಳು]ವನ್ನು ಸೇರುತ್ತಾರೆ.\n\nನಾ$ನ್ಯಂ ಗುಣೇಭ್ಯಃ ಕರ್ತಾರಂ ಯದಾ ದ್ರಷ್ಟಾ 5ನುಪಶ್ಯತಿ |\nಗುಣೇಭ್ಯಶ್ಚ ಪರಂ ವೇತ್ರಿ ಮದ್ಭಾ ವಂ ಸೋಈಧಿಗಚ್ಛತಿ ॥೧೯॥\n\nನ ಅನ್ಯಮ್‌ ಗುಣೇಭ್ಯಃ ಕರ್ತಾರಮ್‌ ಯದಾ ದ್ರಷ್ಟಾ ಅನುಪಶ್ಯತಿ।\n\nಗುಣೇಭ್ಯಃ ಚ ಪರಮ್‌ ವೇತ್ತಿ ಮತ್‌ ಭಾವಮ್‌ ಸಃ ಅಧಿಗಚ್ಛತಿ - ಈ ಎಲ್ಲಾ ಪರಿಣಾಮಗಳಿಗೆ ತ್ರಿಗುಣಗಳಲ್ಲದೆ\nಬೇರೆ ಕಾರಣವಿಲ್ಲ ಎಂದು ಕಂಡುಕೊಂಡವನು[ತ್ರಿಗುಣಗಳಿಂದ ಭಿನ್ನನಾದ ಭಗವಂತನೇ ಎಲ್ಲದರ ಮೂಲ\nಕಾರಣ ಎಂದು ತಿಳಿದವನು] ಮತ್ತು ಗುಣಗಳಿಂದ ಅತೀತನೆಂದು ಭಗವಂತನನ್ನು ತಿಳಿದವನು[ನಿಜವಾದ\nಮನುಷ್ಯ-ಅವನು] ನನ್ನಲ್ಲೇ ನೆಲೆಸುತ್ತಾನೆ.\n\nನಮ್ಮ ಜೀವನದಲ್ಲಿ ಏನೇನು ನಡೆಯುತ್ತದೆಯೋ ಅದೆಲ್ಲವೂ ಈ ಮೂರು ಗುಣಗಳ ಪ್ರಕ್ರಿಯೆ. ನಾವು ನಾವಾಗಿ\nಏನೂ ಮಾಡುವುದಿಲ್ಲ. ಬದಲಿಗೆ ಎಲ್ಲವೂ ತ್ರಿಗುಣಗಳ ಪ್ರಭಾವದಿಂದ ನಡೆಯುತ್ತಿರುತ್ತದೆ. ಪ್ರಕೃತಿಯಿಂದ ಬಂದು,\nನಮ್ಮ ಸ್ವರೂಪವನ್ನು ಮುಚ್ಚಿ ಅವು ಕೆಲಸ ಮಾಡುತ್ತಿರುತ್ತವೆ. ಹಾಗಾಗಿ. ಒಬ್ಬ ವ್ಯಕ್ತಿಯ ಮೇಲ್ನೋಟದ\nವರ್ತನೆಯಿಂದ ಆತನ ನಿಜ ಸ್ವಭಾವವನ್ನು ಅರಿಯುವುದು ಸಾಧ್ಯವಾಗುವುದಿಲ್ಲ. ಈ ಕಾರಣದಿಂದ ನಾವು\nಪ್ರಪಂಚದಲ್ಲಿ ನಡೆಯುವ ಘಟನೆಗಳನ್ನು ನಿರ್ವಿಕಾರರಾಗಿ ಕಾಣಲು ಅಭ್ಯಾಸ ಮಾಡಿಕೊಳ್ಳಬೇಕು.\n\nಸತ್ವಕ್ಕೆ ಶ್ರುತಿಗೂಡಿದ ಮನಸ್ಸು ಸತ್ವಕ್ಕೆ ಅನುಗುಣವಾದ ವಿಷಯವನ್ನೇ ಗ್ರಹಿಸುತ್ತದೆ. ಅಂತಹ ವ್ಯಕ್ತಿ ಎಂದೂ\n“ನಾನು ಮಾಡಿದೆ' ಎಂದು ಭ್ರಮೆ ಪಡುವುದಿಲ್ಲ. ಇಲ್ಲಿ ಗುಣಗಳಿಗಿಂತ ಬೇರೆಯಾದ ಕರ್ತಾ ಇಲ್ಲ ಎಂದಿದ್ದಾರೆ.\nಜಡಕ್ಕೆ ಎಂದೂ ಕರ್ತಾ ಎನ್ನು ವುದಿಲ್ಲ. ಆದ್ದರಿಂದ ಗುಣ ಅಂದರೆ ಕೇವಲ ಜಡವಾದ ಗುಣವಲ್ಲ. ಅದಕ್ಕೆ\nಅಭಿಮಾನಿಯಾದ ಚೈತನ್ಯವನ್ನು ಗುರುತಿಸು ಎನ್ನುವ ಸಂದೇಶ ಈ ಶ್ಲೋಕದಲ್ಲಿದೆ.[ಶ್ಲೋಕ ೧೭ರಲ್ಲಿ ನಾವು ಈ\nಬಗ್ಗೆ ಚರ್ಚಿಸಿದ್ದೇವೆ]. ಕರ್ತೃತ್ವದಲ್ಲಿ ಅನೇಕ ವಿಧ. ಇಚ್ಛಾಪೂರ್ವಕ ಕೃತಿ ಎಲ್ಲಿದೆಯೋ ಅದು ಕರ್ತಾ. ಇದು\nಇರುವುದು ಚೇತನಕ್ಕೆ ಮಾತ್ರ. ಆದರೆ ನಿಜವಾದ ಕರ್ತೃತ್ವ “ಸ್ವತಂತ್ರ ಇಚ್ಛಾಪೂರ್ವಕ ಕೃತಿ'. ಇದು ಇರುವುದು\nಕೇವಲ ಭಗವಂತನಲ್ಲಿ. “ನಾಹಂ ಕರ್ತಾ ಹರಿಃ ಕರ್ತಾ' ಎನ್ನುವ ಪ್ರಸಿದ್ಧವಾದ ಮಾತು ನಮಗೆ ತಿಳಿದೇ ಇದೆ.\nಇದನ್ನು ಮೋಕ್ಷಧರ್ಮಪರ್ವದಲ್ಲಿ ಈ ರೀತಿ ಹೇಳಿದ್ದಾರೆ:\n\nನಾಹಂ ಕರ್ತಾ ನ ಕರ್ತಾ ತ್ವಂ ಕರ್ತಾಯಸ್ತು ಸದಾ ಪ್ರಭುಃ ॥\n\nಸೋತ$ಯಂ ಪಚತಿ ಕಾಲೋ ಮಾಮ್‌ ವೃಕ್ಷೇ ಫಲಂ ಇವಾಗತಂ ॥ ೧೨-೨೨೦-೮೪ ॥\n“ನೀನೂ ಮಾಡಿಲ್ಲ, ನಾನೂ ಮಾಡಿಲ್ಲ- \"ಅವನು' ನಮ್ಮಿಂದ ಮಾಡಿಸಿದ”. ಈ ಎಚ್ಚರ ಇದ್ದಾಗ ನಮಗೆ ಕರ್ತೃತ್ವದ\nಅಹಂಕಾರ ಬರಲು ಸಾಧ್ಯವಿಲ್ಲ. ಇದರಿಂದ ದ್ವೇಷವಿಲ್ಲ, ಮಮಕಾರವಿಲ್ಲ. “ನಾನು ಮಾಡಿದೆ , ನನ್ನಿ ೦ದಾಯ್ತ'\nಎನ್ನುವುದು ಕೇವಲ ಭ್ರಮೆ. ಈ ಜಗತ್ತಿನಲ್ಲಿ ಏನೇ ನಡೆದರೂ ಅದು ಈ ಮೂರು ಗುಣಗಳ ಪ್ರಭಾವದಿಂದ\nನಡೆದಿದೆ. ಅದನ್ನು ಮೀರಿ ನನ್ನಷ್ಟಕ್ಕೆ ನಾನು ಏನೂ ಮಾಡಿಲ್ಲ. ಈ ಅರಿವು ನಮಗೆ ಬರಬೇಕು.\nತ್ರಿಗುಣಗಳ ಪ್ರಭಾವ ಜಡದಲ್ಲೂ ಇದೆ, ಚೇತನದಲ್ಲೂ ಇದೆ. ಅದರ ಪ್ರಭಾವದಿಂದ ಕ್ರಿಯೆ ನಡೆಯುತ್ತದೆ.\nಯಾರೋ ಒಬ್ಬರು ನಿಮಗೆ ಬೈದರು ಎಂದರೆ-ಆತನಲ್ಲಿ ಆ ಕ್ಷಣದಲ್ಲಿ ರಜೋಗುಣ ಜಾಗೃತವಾಗಿ ಕೆಲಸ\nಮಾಡುತ್ತಿದೆ ಎಂದರ್ಥ. ನಾವು ಈ ಅರಿವಿನಿಂದ ಆ ಕ್ಷಣದಲ್ಲಿ ವರ್ತಿಸಬೇಕು. ಇದನ್ನು ಶ್ರೀರಾಮಚಂದ್ರ ತನ್ನ\nಜೀವನದಲ್ಲಿ ನಡೆದು ತೋರಿಸಿದ್ದಾನೆ. ರಾಮಾಯಣದಲ್ಲಿ ವಾಲ್ಮೀಕಿ ಹೇಳುತ್ತಾರೆ:\n\nಸ ಹಿ ನಿತ್ಯಂ ಪ್ರಶಾಂತಂ ಮೃದುಪೂರ್ವಃ ಚ ಭಾಷತೆ |\n\nಉಚ್ಚಮಾನೋಆಪಿ ಪರುಷಮ್‌ ನೋತ್ತರಂ ಪ್ರತಿಪದ್ಯತೆ ॥ಅಯೋಧ್ಯಾ-೧.೧೫॥\nರಾಮನಲ್ಲಿ ಯಾರಾದರೂ ಜಗಳಕ್ಕೆ ನಿಂತರೆ ಆತ ಎಂದೂ ಸಿಟ್ಟಿಗೇಳುತ್ತಿರಲಿಲ್ಲ. “ಮತ್ತೆ ಮಾತನಾಡೋಣ”\nಎಂದು ಹೊರಟು ಹೋಗುತ್ತಿದ್ದನಂತೆ. ಏಕೆಂದರೆ ಒಬ್ಬ ವ್ಯಕ್ತಿಯಲ್ಲಿ ರಜೋಗುಣ ಕೆಲಸ ಮಾಡುತ್ತಿರುವಾಗ,\nಅವರೊಂದಿಗೆ ನಾವು. ರಜೋಗುಣದಿಂದ ವರ್ತಿಸಬೇಕಾದ ಪ್ರಸಂಗ ಬಂದುಬಿಡುತ್ತದೆ. ಇದು ಬಹಳ\nಅಪಾಯಕಾರಿ. ಆದ್ದರಿಂದ ರಜೋಗುಣಕ್ಕೊಳಗಾದವರೊಂದಿಗೆ ನೀನು ರಾಜಸನಾಗಬೇಡ. ತಟಸ್ಥನಾಗಿ ದೂರ\nನಿಲ್ಲು. ಆಗ ಅವರ ರಜೋಗುಣ ತನ್ನಷ್ಟಕ್ಕೆ ಕುಸಿಯುತ್ತದೆ. ಸಿಟ್ಟು ಮಾಡುವವರ ಮುಂದೆ\nಮೌನಿಯಾದರೆ ಅವರ ಸಿಟ್ಟು ಬಹುಬೇಗ ಕರಗುತ್ತದೆ. ಹೀಗೆ ನಾವು ಈ ಗುಣಗಳ ಪ್ರಭಾವವನ್ನು ಗುರುತಿಸಿದಾಗ\nನಮ್ಮ ಬದುಕಿನ ನಡೆಯೂ ಬೇರೆಯಾಗುತ್ತದೆ.\nಮೇಲೆ ಹೇಳಿರುವ ವಿಷಯವನ್ನಷ್ಟೇ ತಿಳಿದರೆ ಸಾಲದು. ಈ ತ್ರಿಗುಣಗಳನ್ನು ಮೀರಿ ನಿಂತವ ಭಗವಂತ. ಅವನನ್ನು\nತಿಳಿದಾಗ ನೀನು ತ್ರಿಗುಣಗಳನ್ನು ಮೀರಿ ನಿಲ್ಲಲು ಸಹಾಯವಾಗುತ್ತದೆ. ಆ ಭಗವಂತನನ್ನು ಸೇರಲು ನಾನು ಈ\nತ್ರಿಗುಣಗಳ ಪ್ರಭಾವದಿಂದ ಹೊರ ಬರಬೇಕು ಎನ್ನುವ ಸತ್ಯವನ್ನು ನಾವು ಅರ್ಥ ಮಾಡಿಕೊಳ್ಳಬೇಕು. “ಇಂಥವರ\nಮನಸ್ಸು ನನ್ನಲ್ಲಿ ನೆಲೆಗೊಳ್ಳುತ್ತದೆ ಮತ್ತು ಅದರಿಂದಾಗಿ ಮುಂದೆ ಅವರು ನನ್ನನ್ನು ಬಂದು ಸೇರಿ ನನ್ನಲ್ಲೇ\nನೆಲೆಸುತ್ತಾರೆ” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.\nಈ ಶ್ಲೋಕಕ್ಕೆ ಇನ್ನೊಂದು ಮುಖವಿದೆ. “ಗುಣೇಭ್ಯಃ ಅನ್ಯಂ ಕರ್ತಾರಂ ಯದಾ ದ್ರಷ್ಟಾ ಅನುಪಶ್ಯತಿ ತದಾ ಸಃ\n'ನಾ' ಭವತಿ”. ಇಲ್ಲಿ “ಗುಣೇಭ್ಯಃ ಅನ್ಯಂ” ಅಂದರೆ ತ್ರಿಗುಣಮಾನಿನಿಯಾಗಿರತಕ್ಕಂತಹ, ಗುಣಶಬ್ದವಾಚ್ಯಳಾದ,\nಶ್ರೀ-ಭೂ-ದುರ್ಗ ನಾಮಕಳಾದ, ಮಹಾಲಕ್ಷ್ಮಿಗಿಂತಲೂ ಅತೀತವಾದ ಒಂದು ಶಕ್ತಿ. ಅವನೇ ನಿಜವಾದ ಕರ್ತಾ.\nಯಾರಾತ? ಮುಂಡಕೋಪನಿಷತ್ತಿನಲ್ಲಿ ಹೇಳುವಂತೆ:\n\nಯದಾ ಪಶ್ಯಃ ಪಶ್ಯತೇ ರುಕ್ಕವರ್ಣಂ ಕರ್ತಾರಮೀಶಂ ಪುರುಷಂ ಬ್ರಹ್ಮಯೋನಿಂ ॥ ೩-೧-೩॥\n\nಯಾರು ಚತುರ್ಮುಖನಿಗೂ ತಂದೆಯೋ, ಯಾರು ಚಿತ್ಛಕೃತಿಗೂ ನಿಯಾಮಕನೋ, ಯಾರು ಸಮಸ್ತ\nವೇದಗಳಿಂದ ವಾಚ್ಯನೋ -ಅವನೊಬ್ಬನೇ ಕರ್ತಾ. ಇದನ್ನು ತಿಳಿದವನು ನಿಜವಾದ ಮಾನವ.\n\nಎಲ್ಲಾ ಅಧ್ಯಾತ್ಮ ಸಾಧನೆ ಮಾಡುವ ಸೌಕರ್ಯವಿರುವ ಶರೀರ-ಮನುಷ್ಯ ಶರೀರ ಮಾತ್ರ. ಅಂತಹ ಶರೀರವನ್ನು\nಉಪಯೋಗಿಸಿಕೊಳ್ಳುವವ ನರ. ಧರ್ಮ-ಅರ್ಥ-ಕಾಮಗಳಿಂದ ಬಿಡಿಸಿಕೊಳ್ಳುವುದು ಎಂದರೆ ಸತ್ವ-ರಜಸ್ಸು-\nತಮೋಗುಣಗಳಿಂದ ಬಿಡಿಸಿಕೊಂಡು ಭಗವಂತನನ್ನು ಸೇರುವುದು. ಇದು ಮನುಷ್ಯನ ಜೀವನದ ಗುರಿ. “ಈ\nಮೂರು ಗುಣಗಳು ನನ್ನಲ್ಲಿ ಕೆಲಸ ನಡೆಸಿವೆ, ನಾನು ಈ ಪ್ರಭಾವದಿಂದ ಕಳಚಿಕೊಂಡು ಮೇಲೇರಬೇಕು” ಎನ್ನುವ\nಎಚ್ಚರವಿರುವುದು ಮನುಷ್ಯನಿಗೆ ಮಾತ್ರ. ಈ ಎಚ್ಚರದಿಂದಾಗಿ “ಮದ್ಭಾವಂ ಸೋಡಧಿಗಚ್ಛತಿ'-ಅವನಲ್ಲಿ\nಭಕ್ತಿಜ್ಞಾನಗಳು ಮನಸ್ಸಿನಲ್ಲಿ ತುಂಬಿ ಆತ ಮೋಕ್ಷವನ್ನು ಸೇರುತ್ತಾನೆ.\n\nಗುಣಾನೇತಾನ",
  "14.19": "ಸತ್ತ್ವಂ ಸುಖೇ ಸಂಜಯತಿ ರಜಃ ಕರ್ಮಣಿ ಭಾರತ ।\nಜ್ಞಾನಮ್‌ ಆವೃತ್ಯ ತು ತಮಃ ಪ್ರಮಾದೇ ಸಂಜಯತಿ ಉತ -ಸತ್ವಗುಣ ಸುಖದ ನಂಟಿನಲ್ಲಿರುತ್ತದೆ. ಭಾರತಾ,\nರಜೋಗುಣ ಕರ್ಮದ ನಂಟಿನಲ್ಲಿರುತ್ತದೆ. ತಮೋಗುಣ ಅರಿವನ್ನು ಮುಚ್ಚಿ ಮೈಮರೆಸಿ ಬಿಡುತ್ತದೆ.\n\nಈ ಶ್ಲೋಕದಲ್ಲಿ ಕೃಷ್ಣ ಮೂರು ಗುಣಗಳನ್ನು ಒಟ್ಟಿನಲ್ಲಿ ಸಂಕ್ಷೇಪಿಸಿ ಹೇಳುತ್ತಾನೆ. ಸತ್ವದ ಮೂಲ ಗುಣಧರ್ಮ\nಏನೆಂದರೆ -ಅದರಿಂದಾಗಿ ನಮ್ಮಿಂದ ಒಂದು ಸಹಜವಾದ ಆನಂದ ಚಿಮ್ಮುತ್ತದೆ. ರಜೋಗುಣ “ಏನಾದರೂ\nಮಾಡಬೇಕು ಇಲ್ಲದಿದ್ದರೆ ಜೀವನದಲ್ಲಿ ಸುಖವಿಲ್ಲ” ಎಂದು, ಸದಾ ದುಡ್ಡಿಗಾಗಿ ಹೋರಾಟ ಮಾಡುತ್ತಾ, ತಮ್ಮ\nಜೀವನವನ್ನು ಸವೆಸುವಂತೆ ಮಾಡುತ್ತದೆ. ತಮಸ್ಸು ನಮ್ಮಲ್ಲಿರುವ ಜ್ಞಾನವನ್ನು ಮುಚ್ಚಿಬಿಡುತ್ತದೆ. ಉದಾಹರಣೆಗೆ:\nಕಷ್ಟದಲ್ಲಿರುವವರಿಗೆ ಸಹಾಯ ಮಾಡಬೇಕು ಎನ್ನುವ ಒಳ್ಳೆಯತನ, ಕೊಡುವುದರಲ್ಲಿ ಖುಷಿಪಡುವುದು-ಸತ್ವಗುಣ.\nತಾನು ಸುಖವಾಗಿರಬೇಕು ಎಂದು ಸದಾ ಸುಖದ ಅನ್ವೇಷಣೆಯಲ್ಲಿ ತೊಡಗಿ, ಮಾಡಬಾರದ ಕೆಲಸವನ್ನು\nಮಾಡುತ್ತಾ ಬದುಕುವುದು ರಜೋಗುಣ. ಸೋಮಾರಿತನ, ನಿದ್ದೆ, ಅಜ್ಞಾನ, ಅದರಿಂದ ಪ್ರಮಾದ ಇವೆಲ್ಲವೂ\nತಮೋಗುಣದ ಪ್ರಭಾವ. ಇದು ನಮಗೆ ಕೃಷ್ಣ ಗೀತೆಯ ಮೂಲಕ ಹೇಳಿದ ಅತ್ಯುನ್ನತವಾದ ಮನಃಶಾಸ್ತ್ರ.\n\nಈ ಗುಣತ್ರಯಗಳು ಹೇಗೆ ನಮ್ಮನ್ನು ನಿಯಂತ್ರಣಕ್ಕೆ ತೆಗೆದುಕೊಂಡು ನಮ್ಮನ್ನು ಕುಣಿಸುತ್ತವೆ ಎನ್ನುವುದನ್ನು\nಕೃಷ್ಣ ನಿರೂಪಿಸಿದ್ದನ್ನು ನೋಡಿದೆವು. ಇಲ್ಲಿ ನಮಗೆ ಒಂದು ಸಂಶಯ ಬರಬಹುದು. ಈ ಮೂರು ಗುಣಗಳು ಒಟ್ಟಿಗೆ\nಏಕಕಾಲದಲ್ಲಿ ಕೆಲಸ ಮಾಡುವಾಗ, ಕೇವಲ ಸಾತ್ವಿಕ ಚಿಂತನೆ, ಕೇವಲ ರಾಜಸ ಚಿಂತನೆ, ಕೇವಲ ತಾಮಸ\n\nಚಿಂತನೆ ಹೇಗೆ ಸಾಧ್ಯವಾಗುತ್ತದೆ? ಮೂರು ಗುಣಗಳು ಒಬ್ಬನ ದೇಹದಲ್ಲಿರುವಾಗ ಯಾವುದೋ ಒಂದು ಗುಣ\nಕೆಲಸ ಮಾಡುವುದು ಹೇಗೆ ಸಾಧ್ಯ? ಮೂರು ಗುಣಗಳು ಬೆರೆತು ನಮ್ಮೊಳಗಿರುವಾಗ ಒಂದು ಪ್ರತ್ಯೇಕವಾದ\nಸಾತ್ವಿಕ ಸ್ವಭಾವ, ರಾಜಸ ಸ್ವಭಾವ, ತಾಮಸ ಸ್ವಭಾವ ಎಂದು ಗುರುತಿಸುವುದು ಹೇಗೆ? ಇದರ ವಿವರಣೆ\nಮುಂದಿನ ಶ್ಲೋಕ.\n\nರಜಸ್ತಮಶ್ಚಾಭಿಭೂಯ ಸತ್ವಂ ಭವತಿ ಭಾರತ ।\n\nರಜಃ ಸತ್ವಂ ತಮಶ್ಚೈವ ತಮಃ ಸತ್ವಂ ರಜಸ್ತಥಾ",
  "14.20": "ಗುಣಾನ್‌ ಏತಾನ್‌ ಅತೀತ್ಯ ತ್ರೀನ್‌ ದೇಹೀ ದೇಹ ಸಮುದ್ಧವಾನ್‌ |\nಜನ್ಮ ಮೃತ್ಯು ಜರಾ ದುಃಖೈಃ ವಿಮುಕ್ತಃ ಅಮೃತಮ್‌ ಅಶ್ನು ತೇ-ದೇಹದಲ್ಲಿ ಮೂಡಿಬರುವ ಈ ಮೂರು\nಗುಣಗಳನ್ನು ದಾಟಿದಾಗ ಜೀವ ಹುಟ್ಟು ಸಾವು ಮುಪ್ಪಿ ನ ದುಃಖದಿಂದಲೂ ಪಾರಾಗಿ ಅಮರನಾಗುತ್ತಾನೆ.",
  "14.21": "ಅರ್ಜುನಃ ಉವಾಚ-ಅರ್ಜುನ ಕೇಳಿದನು:\n\nಕೈಃ ಲಿಂಗೈಃ ತ್ರೀನ್‌ ಗುಣಾನ್‌ ಏತಾನ್‌ ಅತೀತಃ ಭವತಿ ಪ್ರಭೋ ।\n\nಕಿಮ್‌ ಆಚಾರಃ ಕಥಮ್‌ ಚ ಏತಾನ್‌ ತ್ರೀನ್‌ ಗುಣಾನ್‌ ಅತಿವರ್ತತೇ-- ಒಡೆಯನೇ, ಯಾವ ಕುರುಹುಗಳಿಂದ ಈ\nಮೂರು ಗುಣಗಳನ್ನು ದಾಟಿದವನೆನ್ನಿಸುತ್ತಾನೆ ? ಅವನ ನಡೆವಳಿಕೆ ಎಂತಹದು ? ಹೇಗೆ ಈ ಮೂರು\nಗುಣಗಳನ್ನು ದಾಟುತ್ತಾನೆ?\n\nನಮ್ಮ ನಿಮ್ಮೆಲ್ಲರ ಪರವಾಗಿ ಅರ್ಜುನ ಕೃಷ್ಣನಲ್ಲಿ ಪ್ರಶ್ನೆ ಹಾಕುತ್ತಾನೆ. ಆತ ಕೇಳುತ್ತಾನೆ: “ಮೂರು ಗುಣಗಳನ್ನು\nದಾಟಿದವನೊಬ್ಬನಿದ್ದರೆ ಅವನನ್ನು ಗುರುತಿಸುವುದು ಹೇಗೆ? ಆತನ ಕುರುಹು ಏನು? ಅವನ ನಡತೆ\nಹೇಗಿರುತ್ತದೆ? ಈ ಮೂರು ಗುಣಗಳನ್ನು ಆತ ಹೇಗೆ ದಾಟುತ್ತಾನೆ?”\n\nಇಲ್ಲಿ ಅರ್ಜುನ ಕೃಷ್ಣನನ್ನು “ಪ್ರಭೋ” ಎಂದು ಸಂಬೋಧಿಸಿದ್ದಾನೆ. “ನನ್ನ ಪ್ರಶ್ನೆಗಳಿಗೆ ಖಂಡಿತವಾಗಿ ಉತ್ತರ\n\nಕೊಡಬಲ್ಲವ-ನೀನೊಬ್ಬನೆ” ಎನ್ನುವ ಧ್ವನಿ ಮತ್ತು “ಪೂರ್ಣ ಶರಣಾಗತಿ' ಈ ಸಂಬೋಧನೆಯ ಹಿಂದಿದೆ.\nಭಗವಂತ ಅರ್ಜುನನ ಈ ಪ್ರಶ್ನೆಗೆ ಮುಂದಿನ ಶ್ಲೋಕಗಳಲ್ಲಿ ವಿವರವಾಗಿ ಉತ್ತರಿಸಿದ್ದಾನೆ.\n\nಭಗವಾನುವಾಚ ।\nಶಂ ಚ ಪ್ರವೃತ್ತಿಂ ಚ ಮೋಹಮೇವ ಚ ಪಾಂಡವ ।\n\nಕಾ",
  "14.22": "ಭಗವಾನ್‌ ಉವಾಚ-ಭಗವಂತ ಹೇಳಿದನು:\n\nಪ್ರಕಾಶಮ್‌ ಚ ಪ್ರವೃತ್ತಿಮ್‌ ಚ ಮೋಹಮ್‌ ಏವ ಚ ಪಾಂಡವ ।\n\nನ ದ್ವೇಷ್ಟಿ ಸಂಪ್ರವೃತ್ತಾನಿ ನ ನಿವೃತ್ತಾನಿ ಕಾಂಕ್ಷತಿ-ಪಾಂಡವ, ಲೌಕಿಕದ ತಿಳಿವಿನ ಬೆಳಕನ್ನಾಗಲೀ, ಕಾಯಕದ\nಹುರುಪನ್ನಾ ಗಲೀ, ಭ್ರಾಂತಿಯನ್ನೇ ಆಗಲಿ- ಇದ್ದಾಗ ದ್ವೇಷಿಸುವುದಿಲ್ಲ; ಇರದಾಗ ಬಯಸುವುದಿಲ್ಲ.\n\nತ್ರಿಗುಣಗಳನ್ನು ದಾಟಿದವ ಯಾವುದೋ ಅನಪೇಕ್ಷವಾದುದು ಬಂದಾಗ ಅದನ್ನು ದ್ವೇಷಿಸುವುದಿಲ್ಲ;\nಅಪೇಕ್ಷಿತವಾದುದು ಬಾರದೇ ಇದ್ದಾಗ ಅದನ್ನು ಅಪೇಕ್ಷಿಸುವುದಿಲ್ಲ. “ಯಾವುದು ಬೇಕು, ಯಾವುದು ಬೇಡ\nಎನ್ನುವುದು ನನಗಿಂತ ಚೆನ್ನಾಗಿ ಭಗವಂತನಿಗೆ ಗೊತ್ತಿದೆ. ಅದಕ್ಕಾಗಿ ನಾನೇಕೆ ತಲೆ ಕೆಡಿಸಿಕೊಳ್ಳಬೇಕು” ಎನ್ನುವ\nನಿರ್ಲಿಪ್ತತೆ ಆತನಲ್ಲಿರುತ್ತದೆ. ಜೀವನದಲ್ಲಿ ಏನು ಬಂತೋ ಅದನ್ನು ಆತ ಸ್ವಾಗತಿಸುತ್ತಾನೆ. ವ್ಯಾಸರು\nಮಹಾಭಾರತದ ಶಾಂತಿಪರ್ವದಲ್ಲಿ ಒಂದು ಮಾತನ್ನು ಹೇಳಿದ್ದಾರೆ:\nಏವಂ ಅಪ್ಯ ಅಶುಭಂ ಕರ್ಮ ನ ಭೂತಂ ನ ಭವಿಷ್ಯತಿ ॥೧೨-೩೨-೧೮॥\n\n“ಆಗಬಾರದ್ದು ಹಿಂದೆ ಆಗಿಲ್ಲ, ಮುಂದೆ ಆಗುವುದೂ ಇಲ್ಲ. ಏನು ಆಗಬೇಕೋ ಅದು ಘಟಿಸಿಯೇ ತೀರುತ್ತದೆ.\nಅದನ್ನು ನಾನು ಬೇಡ ಎಂದು ದ್ವೇಷಿಸಿ ಫಲವೇನು?”. ಆದ್ದರಿಂದ ತ್ರಿಗುಣವನ್ನು ದಾಟಿದವನು- ಬಂದಾಗ 'ಬೇಡ'\nಎಂದು ದ್ವೇಷಿಸುವುದಿಲ್ಲ; ಇಲ್ಲದ್ದನ್ನು ಬಯಸುವುದೂ ಇಲ್ಲ. ಎಲ್ಲವನ್ನೂ ನಿರ್ವಿಕಾರನಾಗಿ ನೋಡುತ್ತಾ, ತುಂಬಿದ\nಕೊಡದಂತೆ ತುಳುಕದೇ ಬದುಕುತ್ತಾನೆ.\n\nಲೋಕದಲ್ಲಿ ಕೆಲವರಿಗೆ ಸತ್ವದಲ್ಲಿ ಆಸಕ್ತಿಯಾದರೆ ಇನ್ನು ಕೆಲವರಿಗೆ ಕೇವಲ ಪ್ರವೃತ್ತಿ. ಮತ್ತೆ ಕೆಲವರಿಗೆ ಯಾವ\nಆಸಕ್ತಿಯೂ ಇಲ್ಲ- ಕತ್ತಲನ್ನು ಕತ್ತಲು ಎಂದು ತಿಳಿಯದೆ. ಕತ್ತಲಲ್ಲೇ ಬದುಕುವವರಿದ್ದಾರೆ. ಇದು\nಸರ್ವೇಸಾಮಾನ್ಯವಾಗಿ ಕಾಣುವ ವಿಚಾರ. ತ್ರಿಗುಣವನ್ನು ಮೀರಿ ನಿಂತವರು ಇದನ್ನು ನೋಡಿ ತಮ್ಮ ಮನಸ್ಸನ್ನು\nವಿಕಾರ ಮಾಡಿಕೊಳ್ಳುವುದಿಲ್ಲ. “ಅವರವರ ಗುಣ ಪ್ರಭಾವಕ್ಕನುಗುಣವಾಗಿ ಎಲ್ಲವೂ ನಡೆಯುತ್ತಿದೆ” ಎಂದು\n\nತಿಳಿದು ತಟಸ್ಥರಾಗಿ ಬದುಕುತ್ತಾರೆ. ಸತ್ಯವೆಂದು ಕಂಡದ್ದನ್ನು ಇವರು ಹೇಳುತ್ತಾರೆ. ಆದರೆ ಎಂದೂ ವಾದ\nವಿವಾದವನ್ನು ಬೆಳೆಸುವುದಿಲ್ಲ. “ಎಲ್ಲವೂ ಭಗವಂತನ ಲೀಲೆ, ಆತ ಮಾಡಿದ ವ್ಯವಸ್ಥೆ” ಎಂದು ಎಲ್ಲವನ್ನು\nಸ್ವೀಕರಿಸುತ್ತಾರೆ. ಗೀತೆಯ ಹನ್ನೆರಡನೇ ಅಧ್ಯಾಯದಲ್ಲಿ \"ನಿಜವಾದ ಭಕ್ತ' ಹೇಗಿರುತ್ತಾನೆ ಎಂದು ವಿವರಿಸುವಾಗ\nಕೃಷ್ಣ ಈ ಶ್ಲೋಕದಲ್ಲಿ ಕೊಟ್ಟ ವಿವರಣೆಯನ್ನೇ ಕೊಟ್ಟಿದ್ದಾನೆ. ಇದರ ಅರ್ಥ- ಹೊರಗಿನ ಗುಣವನ್ನು ಮೀರಿ\nನಿಲ್ಲುವುದೇ ನಿಜವಾದ ಭಕ್ತಿ.\n\nಇಲ್ಲಿ ವ್ಯಾಸರು \"ಪಾಂಡವ' ಎನ್ನುವ ವಿಶೇಷಣವನ್ನು ಬಳಸಿದ್ದಾರೆ. ಪಾಂಡಾ ಎಂದರೆ ಜ್ಞಾನಿ. ಪಾಂಡವ ಎಂದರೆ\nಜ್ಞಾನವನ್ನು ಗುರುತಿಸಿ ತಲೆಬಾಗುವವನು. “ತ್ರಿಗುಣಾತೀತನಾಗುವ ಮೊದಲು ನೀನು ಪಾಂಡವನಾಗಬೇಕು”\nಎನ್ನುವ ಸಂದೇಶ ಈ ವಿಶೇಷಣದ ಹಿಂದಿದೆ.\n",
  "14.23": "ಉದಾಸೀನವತ್‌ ಆಸೀನಃ ಗುಣೈಃ ಯಃ ನ ವಿಚಾಲ್ಯತೇ ।\n\nಗುಣಾಃ ವರ್ತಂತ ಇತಿ ಏವಮ್‌ ಯಃ ಅವತಿಷ್ಠತಿ ನ ಇಂಗತೇ -ಉದಾಸೀನನಂತೆ ಇದ್ದುಬಿಡುತ್ತಾನೆ. ಗುಣಗಳ\nಸೆಳೆತಕ್ಕೆ ಕದಲುವುದಿಲ್ಲ. ಗುಣಗಳು ಇರುವಂತವೇ ಎಂದು ತೆಪ್ಪಗೆ ಇದ್ದು ಬಿಡುತ್ತಾನೆ. ಅವುಗಳ ತಾಳಕ್ಕೆ ತಾನು\nಕುಣಿಯುವುದಿಲ್ಲ.\n\nಪ್ರಾಪಂಚಿಕ ವ್ಯವಹಾರದಲ್ಲಿ ಈತ ಉದಾಸೀನನಂತೆ ಇದ್ದುಬಿಡುತ್ತಾನೆ. ನಮಗೆ ಬೇಕು ಬೇಡಗಳು ಬರುವುದು\nತ್ರಿಗುಣಗಳಿಂದ. ತ್ರಿಗುಣಾತೀತ- “ಹಾಗಾಗಬೇಕು-ಹೀಗೇ ಆಗಬೇಕು” ಎಂದು ಬಯಸುವುದಿಲ್ಲ.\n“ಹೇಗಾಗಬೇಕೋ ಹಾಗೇ ಭಗವಂತ ಮಾಡುತ್ತಾನೆ” ಎನ್ನುವ ನಂಬಿಕೆ ಅವನಲ್ಲಿರುತ್ತದೆ.[ಇಲ್ಲಿ ಒಂದು\nವಿಷಯವನ್ನು ನಾವು ತಿಳಿದುಕೊಳ್ಳಬೇಕು. ಪ್ರಪಂಚದಲ್ಲಿ ನಡೆಯುವ ಘಟನೆಗಳು ನಮ್ಮ ಅಧೀನವಲ್ಲ. ನಾವು\nಆಗಬಾರದು ಅಂದುಕೊಳ್ಳುವುದು ಆಗಬಹುದು, ಆಗಬೇಕು ಅಂದುಕೊಳ್ಳುವುದು ಆಗದೇ ಇರಬಹುದು.\nಹೀಗಿರುವಾಗ “ಹೀಗೇ ಆಗಬೇಕು' ಎಂದು ವ್ಯರ್ಥವಾಗಿ ಮನಸ್ಸ ನ್ನು ಉದ್ವೇಗಕ್ಕೊಳಪಡಿಸುವುದರಲ್ಲಿ ಅರ್ಥವಿಲ್ಲ].\nಹೀಗೆ ಬದುಕಿದಾಗ-ಬಯಸಿದ್ದು ಆಗದಿದ್ದಾಗ ಕೋಪವಿಲ್ಲ, ಆದಾಗ ಹಾರಾಟವಿಲ್ಲ. ಮನಸ್ಸು ಪ್ರಸನ್ನವಾಗಿರುತ್ತದೆ.\n\nಇಂದ್ರಿಯಗಳು ಗುಣಗಳಲ್ಲಿ ಇರುತ್ತವೆ, ಇಂದ್ರಿಯಗಳ ಹಿಂದೆ ಗುಣಗಳಿರುತ್ತವೆ. ಆದರೆ ತ್ರಿಗುಣಾತೀತ\nಇವೆಲ್ಲವನ್ನೂ ತಿಳಿದು, ತಲೆಕೆಡಿಸಿಕೊಳ್ಳದೇ, ಯಾವುದೇ ಕ್ರಿಯೆಯಲ್ಲಿ ಕೂಡಾ[ತಾತ್ಕಾಲಿಕ ಕ್ರಿಯೆಯಲ್ಲಿ ಕೂಡಾ]\nಚಪಲವಿಲ್ಲದೆ ಬದುಕುತ್ತಾನೆ.\n",
  "14.24": "ಸಮ ದುಃಖಸುಖಃ ಸ್ವಸ್ಥಃ ಸಮ ಲೋಷ್ಟ ಆಶ್ಮ ಕಾಂಚನಃ ।\n\nತುಲ್ಯ ಪ್ರಿಯ ಅಪ್ರಿಯಃ ಧೀರಃ ತುಲ್ಕ ನಿಂದಾತ್ಮ ಸಂಸ್ತುತಿಃ - ಸುಖ-ದುಃಖವನ್ನು ಸಮನಾಗಿ ಕಾಣುತ್ತಾನೆ.\nತನ್ನಲ್ಲೇ ತಾನು ಇದ್ದುಬಿಡುತ್ತಾನೆ. ಮಣ್ಣು, ಕಲ್ಲು, ಚಿನ್ನ ಅವನಿಗೆ ಒಂದೇ ತರಹ. ಸಾಧನೆಯಿಂದ ಬಗೆ ಗಟ್ಟಿಗೊಂಡ\nಅವನಿಗೆ ಪ್ರಿಯವೂ ಒಂದೇ; ಅಪ್ರಿಯವೂ ಒಂದೇ. ತೆಗಳಿಕೆಯೂ ಒಂದೆ. ಹೊಗಳಿಕೆಯೂ ಒಂದೇ.\n\nತ್ರಿಗುಣಾತೀತ ಸರ್ವ ಸುಖ-ದುಃಖವನ್ನೂ ಸಮನಾಗಿ ಕಾಣುತ್ತಾನೆ. ಏಕೆಂದರೆ ನಮಗೆ ಮೇಲ್ನೋಟಕ್ಕೆ\nಸುಖವೆಂದು ಕಾಣುವುದು ನಿಜವಾಗಿ ಸುಖವಾಗಿ ಇರಬೇಕೆಂದೇನೂ ಇಲ್ಲ. ಅದೇ ರೀತಿ ದುಃಖ ಕೂಡಾ. ಇದನ್ನು\nತಿಳಿದಾಗ ಎಲ್ಲವೂ ಭಗವಂತನ ಲೀಲೆ ಎನ್ನುವ ಭಾವನೆ ಮನಸ್ಸಿನಲ್ಲಿ ಹುಟ್ಟುತ್ತದೆ. ಆಗ ಎಲ್ಲವನ್ನೂ ಸಮನಾಗಿ\nಕಾಣುವ ಕ್ಷಮತೆ ನಮ್ಮಲ್ಫಿ ಬೆಳೆಯುತ್ತದೆ.\nನಾವು ಹೇಗೆ ನಾಟಕದಲ್ಲಿ ನಡೆಯುವ ದೃಶ್ಯವನ್ನು ಪ್ರೇಕ್ಷಕರಂತೆ ಕಾಣುತ್ತೇವೋ, ಹಾಗೇ ಪ್ರಪಂಚದಲ್ಲಿ\nನಡೆಯುವ ಘಟನೆಗಳನ್ನು ಪ್ರೇಕ್ಷಕರಂತೆ ಕಾಣಲು ಅಭ್ಯಾಸ ಮಾಡಿಕೊಳ್ಳಬೇಕು. ಅದು ಸುಖಮಯವಿರಬಹುದು,\nದುಃಖಮಯವಿರಬಹುದು-ಆದರೆ ನಾವು. ಭಗವಂತನ ಒಂದೊಂದು ಕ್ರಿಯಯನ್ನೂ ಆಸ್ವಾಧಿಸಬೇಕು.\nಜೀವನದಲ್ಲಿ ಬರುವ ತಾತ್ಕಾಲಿಕ ದುಃಖ ನಮ್ಮ ಶಾಶ್ವತ ಸುಖಕ್ಕೆ ಕಾರಣವಾಗಿರುತ್ತದೆ. ಆದರೆ ಅದು ನಮಗೆ\nತಿಳಿದಿರುವುದಿಲ್ಲ ಅಷ್ಟೆ. ತ್ರಿಗುಣಾತೀತರು ಈ ವಿಷಯವನ್ನು ಅರಿತು ಸುಖ-ದುಃಖವನ್ನು ಸಮನಾಗಿ ಕಾಣುತ್ತಾ\nಆನಂದದಿಂದ ಬದುಕುತ್ತಿರುತ್ತಾರೆ.\nಹಿಂದೆ ಸ್ಥಿತಪ್ರಜ್ಞ ಮತ್ತು ಭಕ್ತರ ಲಕ್ಷಣ ಹೇಳುವಾಗ ಹೇಳಿದ ಮಾತುಗಳನ್ನು ಕೃಷ್ಣ ಇಲ್ಲಿ ಮತ್ತೆ\nಪುನರುಚ್ಛರಿಸುತ್ತಾನೆ. ತ್ರಿಗುಣಾತೀತನಿಗೆ ಮಣ್ಣು, ಅಮೂಲ್ಯ ರತ್ನ ಸ; ಚಿನ್ನ -ಎಲ್ಲವೂ ಒಂದೇ. ಆತನಿಗೆ\nಚಿನ್ನ ವಾಗಲೀ, ರತ್ನ ವಾಗಲೀ ಅಮೂಲ್ಯ ಎಂದು ಕಾಣುವುದಿಲ್ಲ. ಆತನಿಗೆ ಅಮೂಲ್ಯ-ಜ್ಞಾನವೊಂದೇ. ಈ\nಕಾರಣದಿಂದ ಆತ ಹಣದಲ್ಲಾಗಲಿ, ಮುತ್ತು-ರತ್ನ ದಲ್ಲಾಗಲಿ, ಬಂಗಾರದಲ್ಲಾಗಲಿ ಯಾವುದೇ ರೀತಿಯ ಅಭಿಲಾಷೆ\nತೋರುವುದಿಲ್ಲ. ಆದ್ದರಿಂದ ಆತ ಸಂತೋಷದಿಂದ ಬದುಕುತ್ತಾನೆ. ಭಾಗವತದ ಮೂರನೇ ಸ್ಕಂದದಲ್ಲಿ ಬರುವ\nಒಂದು ಶ್ಲೋಕ ಈ ರೀತಿ ಹೇಳುತ್ತದೆ:\n\nಯಶ್ಚ ಮೂಢತಮೋ ಲೋಕೇ ಯಶ್ಚ ಬುದ್ಧೇಃ ಪರಂ ಗತಃ\n\nತಾವುಭೌ ಸುಖಮೇಧೇತೇ ಕ್ಲಿಶ್ಯತ್ಯಂತರಿತೋ ಜನಃ ॥೩-೭-೧೭॥|\nಒಬ್ಬ ಮೂಢ ಮತ್ತು ಇನ್ನೊ ಬ್ಬ ಜ್ಞಾನಿ- ಇವರಿಬ್ಬರು ಲೋಕದಲ್ಲಿ ಸುಖದಿಂದ ಬದುಕಬಲ್ಲರು ಎಂದು. ಏಕೆಂದರೆ\nಇವರಿಗೆ ಹಣದ ಮೋಹವಿರುವುದಿಲ್ಲ. ಆದರೆ ಇವೆರಡರ ಮಧ್ಯದಲ್ಲಿರುವವರು-ಜೀವನದ ಅರ್ಥ ತಿಳಿಯದೆ\nಮೋಹಕ್ಕೆ ಬಲಿಯಾಗಿ ದುಃಖ ಅನುಭವಿಸುತ್ತಾರೆ.\nಹೇಗೆ ಜ್ಞಾನಿಗಳು ತಮ್ಮ ಜೀವನದಲ್ಲಿ ಈ ತತ್ವವನ್ನು ಅಳವಡಿಸಿಕೊಂಡು ಬದುಕುತ್ತಾರೆ ಎನ್ನುವುದಕ್ಕೆ ರಾಮಕೃಷ್ಣ\nಪರಮಹಂಸರ ಜೀವನ ಚರಿತ್ರೆ ಉತ್ತಮ ನಿದರ್ಶನ. ಮೈಸೂರು ಮಹಾರಾಜರ ಕಾಲದಲ್ಲಿ ಸೋದೆಮಠದ\nಸ್ವಾಮಿಗಳಾಗಿದ್ದ ವಿಶ್ವಪ್ರಿಯತೀರ್ಥರು (ವೃಂದಾವನಾಚಾರ್ಯರು) ಬದುಕಿದ ಜೀವನ ಶೈಲಿ ಇದಕ್ಕೆ ಇನ್ನೊಂದು\nಉತ್ತಮ ದೃಷ್ಟಾಂತ.\n\nಈ ಶ್ಲೋಕವನ್ನು ಇನ್ನೊಂದು ಮುಖದಲ್ಲಿ ನೋಡಿದಾಗ ನಮಗೆ ಇನ್ನೂ ಒಂದು ವಿಶೇಷ ಸಂದೇಶ ತಿಳಿಯುತ್ತದೆ.\nಒಬ್ಬ ನಿಜವಾದ ಭಕ್ತ(ತ್ರಿಗುಣಾತೀತ)ನ ಭಗವದ್‌ ಭಕ್ತಿ ಆತನ ಜೀವನದಲ್ಲಿ ಬರುವ ಸುಖ-ದುಃಖಗಳಿಂದ\nಏರುಪೇರಾಗುವುದಿಲ್ಲ. ಬಡತನವಿರಲಿ-ಸಿರಿತನವಿರಲಿ ಈತ ನಿರಂತರ ಭಗವಂತನ ಭಕ್ತಿಯಲ್ಲಿ ತೊಡಗಿರುತ್ತಾನೆ.\nಈತನ ಭಕ್ತಿಗೆ ಇನ್ನೊಬ್ಬರ ಪ್ರೀತಿ-ದ್ವೇಷ ಎಂದೂ ಮಾನದಂಡವಲ್ಲ. ಈ ರೀತಿ ತ್ರಿಗುಣಾತೀತರು ಎಲ್ಲಾ\nಸ್ಥಿತಿಯಲ್ಲೂ ಸಮಾನತೆಯಿಂದ ಬದುಕುತ್ತಾರೆ.\n",
  "14.25": "ಮಾನ ಅಪಮಾನಯೋಃ ತುಲ್ಯಃ ತುಲ್ಯಃ ಮಿತ್ರ ಅರಿ ಪಕ್ಷಯೋಃ ।\nಸರ್ವಾರಂಭ ಪರಿತ್ಯಾಗೀ ಗುಣಾತೀತಃ ಸಃ ಉಚ್ಯತೇ ಎ ಸಮ್ಮಾನವೂ ಒಂದೇ; ಅಪಮಾನವೂ ಒಂದೇ.\nಗೆಳೆಯರ ಬಳಗವೂ ಒಂದೇ; ಹಗೆಯರ ಬಳಗವೂ ಒಂದೇ. ಅವನು ಇಂತಹ ಯಾವ ಲೌಕಿಕದಲ್ಲೂ\nತೊಡಗಿಕೊಳ್ಳುವುದಿಲ್ಲ. ಅಂತವನು 'ಗುಣಾತೀತ' ಎನ್ನಿಸುತ್ತಾನೆ.\n\nತ್ರಿಗುಣಾತೀತರನ್ನು ಒಬ್ಬರು 'ಮಹಾನ್‌ ಜ್ಞಾನಿ' ಎಂದು ಸಮ್ಮಾನಿಸಿ ಮಾತನಾಡಬಹುದು, ಇನ್ನೊಬ್ಬ ರು ಆತ\n'ಅರೆಹುಚ್ಚ'. ಎಂದು ನಿಂದಿಸಬಹುದು. ಆದರೆ ಇದ್ಯಾವುದೂ ಅವರ ಮೇಲೆ ಪರಿಣಾಮಬೀರದು. ಇವರಿಗೆ\nಸ್ನೇಹಿತರು ಎನ್ನುವ ಮೋಹವಾಗಲೀ, ಶತ್ರುಗಳು ಎನ್ನು ವ ದ್ವೇಷವಾಗಲೀ ಇರುವುದಿಲ್ಲ. ಇವರು ಎಲ್ಲರನ್ನೂ\nಅವರವರ ಯೋಗ್ಯತೆಗೆ ತಕ್ಕಂತೆ ಕಾಣುತ್ತಾ, ಭಗವಂತನ ಭಕ್ತಿಗೆ ವಿರುದ್ಧವಾದ ಯಾವ ಚಟುವಟಿಕೆಯಲ್ಲೂ\nತೊಡಗದೇ ಬದುಕುತ್ತಾರೆ. ಇವರು. ದೀರ್ಥಕಾಲದ ಯಾವುದೇ ಯೋಜನೆಯಲ್ಲಿ ತಮ್ಮನ್ನು ತಾವು\nತೊಡಗಿಸಿಕೊಳ್ಳುವುದಿಲ್ಲ.\n\nಹೀಗೆ ಮೇಲಿನ ನಾಲ್ಕು ಶ್ಲೋಕದಲ್ಲಿ ಗುಣಾತೀತರ ಸ್ವಭಾವದ ಪೂರ್ಣ ಚಿತ್ರಣವನ್ನು ಕೃಷ್ಣ ಸುಂದರವಾಗಿ\nವರ್ಣಿಸಿದ. ಈ ಸ್ವಭಾವವುಳ್ಳವರನ್ನು ನಾವು ಗುಣಾತೀತರೆಂದು ಗುರುತಿಸಬಹುದು.\n\nಇಲ್ಲಿಯ ತನಕ ತ್ರಿಗುಣಗಳ ಬಗ್ಗೆ ಮತ್ತು ತ್ರಿಗುಣಾತೀತರ ಸ್ವಭಾವದ ಬಗ್ಗೆ ವಿವರಿಸಿದ ಕೃಷ್ಣ, ಕೊನೆಯ ಎರಡು\nಶ್ಲೋಕದಲ್ಲಿ ನಾವು ತ್ರಿಗುಣಾತೀತರಾಗುವ ಬಗೆ ಹೇಗೆ ಎನ್ನುವುದನ್ನು ವಿವರಿಸುತ್ತಾನೆ. ನಮ್ಮ ಎಲ್ಲಾ\nಪ್ರವೃತ್ತಿಯೂ ಈ ಮೂರು ಗುಣಗಳ ಪರಿಮಿತಿಯಲ್ಲಿ ಇರುವಾಗ ತ್ರಿಗುಣವನ್ನು ಮೀರಿ ನಿಲ್ಲುವುದು ನಮಗೆ\nಕಲ್ಪನಾತೀತ. ಹಾಗಾಗಿ ಇಲ್ಲಿ ಕೃಷ್ಣ ನಮಗೆ ತ್ರಿಗುಣಾತೀತರಾಗಲು ಇರುವ ಏಕಮಾತ್ರ ಮಾರ್ಗವನ್ನು\nವಿವರಿಸುತ್ತಾನೆ.",
  "14.26": "ಮಾಮ್‌ ಚ ಯಃ ಅವ್ಯಭಿಚಾರೇಣ ಭಕ್ತಿಯೋಗೇನ ಸೇವತೇ ।\n\nಸಃ ಗುಣಾನ್‌ ಸಮತೀತ್ಯ ಏತಾನ್‌ ಬ್ರಹ್ಮಭೂಯಾಯ ಕಲ್ಪತೇ - ನನ್ನನ್ನು ಎಡೆಬಿಡದೆ ಭಕ್ತಿಯಿಂದ\nಆರಾಧಿಸುವವನು. ಈ ಗುಣಗಳ ಕಟ್ಟನ್ನು ಹರಿದು, ಚೇತನ ಪ್ರಕೃತಿಯಂತೆ ಭಗವಂತನ ಭಕ್ತಿಗೆ\nಪಾತ್ರನಾಗುತ್ತಾನೆ.[ಚೇತನ ಪ್ರಕೃತಿಯನ್ನು ಸೇರುತ್ತಾನೆ].\n\nನಾವು ನಾವಾಗಿ ತ್ರಿಗುಹಾತೀತರಾಗಬೇಕು ಎಂದು ಪ್ರಯತ್ನಿಸಿದರೆ ಆ ಪ್ರಯತ್ನದಲ್ಲಿ ನಾವು ಯಶಸ್ಸನ್ನು ಕಾಣಲು\nಸಾಧ್ಯವಿಲ್ಲ. ಏಕೆಂದರೆ ನಮ್ಮ ಎಲ್ಲಾ ಯೋಚನೆ ತ್ರಿಗುಣದಲ್ಲೇ ಸುತ್ತುತ್ತಿರುತ್ತದೆ. ಇದೊಂದು ಚಕ್ರಭ್ರಮಣ. ಈ ಚಕ್ರ\nಭ್ರಮಣದಿಂದ ಪಾರು ಮಾಡಲು ಆ ಚಕ್ರಧಾರಿಯೇ ಬರಬೇಕು. ದ್ವಾದಶಸ್ತೋತ್ರದಲ್ಲಿ ಹೇಳುವಂತೆ:\n“ತ್ರಿಗುಣಾತೀತ ವಿಧಾರಕ ಪರಿತೋ ದೇಹಿ ಸುಭಕ್ತಿಮ್‌”. ತ್ರಿಗುಣಾತೀತರನ್ನು ಧಾರಣೆ ಮಾಡುವವ ಆ\nಭಗವಂತ. ಆದ್ದರಿಂದ ತ್ರಿಗುಣಾತೀತರಾಗಲು ಇರುವ ಮಾರ್ಗ ಒಂದೇ-ಆ ಭಗವಂತನಲ್ಲಿ ಶರಣಾಗುವುದು.\nಲಕ್ಷ್ಮೀಸಮೇತನಾದ ಆ ಭಗವಂತನಲ್ಲಿ ಏಕನಿಷ್ಠೆಯಿಂದ ಅನನ್ಯ ಭಕ್ತಿ ಮಾಡುವುದರಿಂದ - ಲಕ್ಷ್ಮಿಯಿಂದ\nಹದಿನೈದು ಬಂಧನದ ಬೇಲಿಯನ್ನು ಧರಿಸಿ ಪ್ರಪಂಚಕ್ಕೆ ಬಂದ ಸಾವು, ಈ ಎಲ್ಲಾ ಬಂಧವನ್ನು ಕಳಚಿಕೊಂಡು\nಮರಳಿ ತಾಯಿಯ ಮಡಿಲನ್ನು ಸೇರಬಹುದು.\n",
  "14.27": "ಬ್ರಹ್ಮಣಃ ಹಿ ಪ್ರತಿಷ್ಠಾ ಅಹಮ್‌ ಅಮೃತಸ್ಯ ಅವ್ಯಯಸ್ಯ ಚ |\nಶಾಶ್ವತಸ್ಯ ಚ ಧರ್ಮಸ್ಯ ಸುಖಸ್ಯ ಐಕಾಂತಿಕಸ್ಯ ಚ -ಅಳಿವಿರದ ಬದಲಾಗದ ಚಿತ್‌ ಪ್ರಕೃತಿಗೂ ನಾನೇ ಆಸರೆ-\n\nನೆಲೆ. ಸನಾತನ ಧರ್ಮಕ್ಕೆ ಮತ್ತು ಕೇವಲ ಸುಖಮಯವಾದ ಮೋಕ್ಷಕ್ಕೆ ಕೂಡಾ.\n\nಮೂರು ಗುಣಗಳನ್ನು ಮೀರಿ ನಿಂತಾಗ ಜೀವದ ಸಹಜ-ಶಾಶ್ವತ ಧರ್ಮ ಅಭಿವ್ಯಕ್ತವಾಗುತ್ತದೆ. ಈ ಸ್ಥಿತಿಯಲ್ಲಿ\nಬ್ರಹ್ಮತತ್ವವಾದ ಚಿತ್‌ ಪ್ರಕೃತಿ ಉಲ್ಲೇಖ ಮಾಡುತ್ತಾರೆ. ಏಕೆಂದರೆ ಈ ಶ್ಲೋಕಗಳಲ್ಲೇ\nಆಚಾರ್ಯರ ಎಲ್ಲಾ ಸಿದ್ಧಾಂತದ ಸಾರ ಅಡಗಿದೆ.\n\nಹಿಂದಿನ ಕಾಲದಲ್ಲಿ ಒಂದು ಸಂಪ್ರದಾಯವಿತ್ತು. ಊಟಕ್ಕೆ ಕುಳಿತಾಗ, ಊಟ ಪ್ರಾರಂಭಿಸುವ ಪೂರ್ವದಲ್ಲಿ ಈ\nಅಧ್ಯಾಯದ ಶ್ಲೋಕವನ್ನು ಹೇಳಿ ಆಮೇಲೆ ಊಟ ಮಾಡುವುದು. \"ಊಟದ ಎಲೆಯ ಮುಂದೆ ಇಡೀ ಶಾಸ್ತ್ರದ\nಸಾರವನ್ನು ನಾವು ಅನುಸಂಧಾನ ಮಾಡಿದಂತಾಯಿತು' ಎನ್ನುವುದು ಆ ಸಂಪ್ರದಾಯದ ಹಿಂದಿನ ಕಾರಣ.\nಹದಿಮೂರನೇ ಅಧ್ಯಾಯದಲ್ಲಿ ಕ್ಷೇತ್ರ ಮತ್ತು ಕ್ಷೇತ್ರಜ್ಞರ ಬಗ್ಗೆ ಕೃಷ್ಣ ವಿವರಿಸಿದ್ದ. ವಿಶ್ವ ಮತ್ತು ವಿಶ್ವದ ನಿಯಾಮಕ\nಭಗವಂತನ ವಿಷಯವನ್ನೇ ಇನ್ನೂ ಸ್ಪಷ್ಟವಾಗಿ, ಇನ್ನೊಂದು ಮುಖದೊಂದಿಗೆ ಈ ಅಧ್ಯಾಯದಲ್ಲಿ ಕೃಷ್ಣ\nವಿವರಿಸುತ್ತಾನೆ. ಪ್ರಕೃತಿ ಮತ್ತು ಪ್ರಾಕೃತ ವಿಶ್ವ, ಆ ವಿಶ್ವವನ್ನು ದಾಟುವ ಬಗೆ ಮತ್ತು ಕೊನೆಯದಾಗಿ ಇಡೀ\nತತ್ವಜ್ಞಾನದ ಸಂಗ್ರಹ ಈ ಅಧ್ಯಾಯದಲ್ಲಿದೆ. ನಾವು ತಿಳಿದುಕೊಳ್ಳಬೇಕಾದ ವಿಶಿಷ್ಟವಾದ ಅರಿವಿನ ಸಂದೇಶವನ್ನು\nಕೃಷ್ಣ ಈ ಅಧ್ಯಾಯದ ಮೂಲಕ ಕೊಟ್ಟಿದ್ದಾನೆ.\n\nಚೇತನಾಚೇತನ ವಿಶ್ವ-ಕ್ಷರ'. ಅದರಿಂದಾಚೆಗೆ ಇರುವ ಚಿತ್ಛ್ರಕೃತಿ-'ಅಕ್ಷರ'ಳು. ಅದರಿಂದಾಚೆಗಿರುವ ಸರ್ವ\nನಿಯಾಮಕ ಭಗವಂತ-'ಪುರುಷೋತ್ತಮ'. ಹನ್ನೆರಡನೇ ಅಧ್ಯಾಯದ ಪ್ರಾರಂಭದಲ್ಲಿ ವಿವರಿಸಿದಂತೆ- ಹದಿನೈದು\nಬೇಲಿಗಳಿಂದ ಆವೃತವಾಗಿರುವ ಹದಿನಾರನೆಯವ ಜೀವ. ಈ ಹದಿನೈದನ್ನು ಹದಿನಾರರ ಸುತ್ತ ಬಿಗಿದವಳು\nಹದಿನೇಳನೆಯವಳಾದ ಶ್ರೀಲಕ್ಷ್ಮಿ. ಈ ಬೇಲಿಯಿಂದ ಬಿಡಿಸಿ ನಮಗೆ ಮೋಕ್ಷ ಕೊಡತಕ್ಕವನು\nಹದಿನೆಂಟನೆಯವನಾದ ಪುರುಷೋತ್ತಮ. [ಈ ಹದಿನೈದು ಬೇಲಿಗಳ ಬಗ್ಗೆ ವಿವರವಾಗಿ ತಿಳಿಯಲು\nಪ್ರಶ್ನೋಪನಿಷತ್ತಿನ ಆರನೇ ಪ್ರಶ್ನೆಯನ್ನು ನೋಡಿ. ಶ್ರದ್ಧಾಂ ಖಂ ವಾಯುಃ ಜ್ಯೋತಿಃ ಆಪಃ ಪೃಥಿವಿ ಇಂದ್ರಿಯಂ\nಮನಃ | ಅನ್ನಮನ್ನಾದಿ ವೀರ್ಯಂ ತಪೋ ಮಂತ್ರಾಃ ಕರ್ಮ ಲೋಕಾಃ ಲೋಕೇಷು ಚ ನಾಮ ಚ ॥ ೬-೪॥ ಇವೇ\nಆ ಹದಿನೈದು ಬೇಲಿಗಳು].\n\n“ಹದಿನೆಂಟು' ತತ್ವಶಾಸ್ತ್ರದ ಸಮಷ್ಠಿಯನ್ನು ನಮ್ಮ ಮುಂದಿಡತಕ್ಕಂತಹ ಒಂದು ಸಂಖ್ಯೆ. ಈ ಅಧ್ಯಾಯದಲ್ಲಿ\nಹದಿನೆಂಟು ಶ್ಲೋಕಗಳ ಮೂಲಕ ಕೃಷ್ಣ ಸಮಸ್ತ ಶಾಸ್ತ್ರದ ಸಾರವನ್ನು ನಮ್ಮ ಮುಂದೆ ತೆರೆದಿಟ್ಟಿದ್ದಾನೆ. ಬನ್ನಿ ಈ\nಅಪೂರ್ವ ಅಧ್ಯಾಯವನ್ನು ಕೃಷ್ಣನಿಂದ ಕೇಳಿ ತಿಳಿಯೋಣ.\n\nಭಗವಾನುವಾಚ ।\nಊರ್ದ್ವಮೂಲಮಧಃಶಾಖಮಶ್ವತ್ಥಂ ಪ್ರಾಹುರವ್ಯಯಮ್‌ |\nಛಂದಾಂಸಿ ಯಸ್ಯ ಪರ್ಣಾನಿ ಯಸ್ತಂ ವೇದ ಸ ವೇದವಿತ್‌ ॥೧॥\n\nಭಗವಾನ್‌ ಉವಾಚ-ಭಗವಂತ ಹೇಳಿದನು:\n\nಊರ್ಧ್ವಮೂಲಮ್‌ ಅಧಃ ಶಾಖಮ್‌ ಅಶ್ವತ್ಥಮ್‌ ಪ್ರಾಹುಃ ಅವ್ಯಯಮ್‌ |\n\nಛಂದಾಂಸಿ ಯಸ್ಯ ಪರ್ಣಾನಿ ಯಸ್ತಂ ವೇದ ಸಃ ವೇದವಿತ್‌ -ಮೇಲಿರುವ ಭಗವಂತ ಮತ್ತು ಪ್ರಕೃತಿ ವಿಶ್ವದ\nಬುಡಕಟ್ಟು. ಕೆಳಗಿನ ಜೀವ-ಜಡಗಳು ಇದರ ಟೊಂಗೆ-ಟಿಸಿಲು. ಇದು ಎಂದೆಂದೂ ಇರುವ[|[ಅ*ಶ್ವಃ*ತ್ಥ- ಇಂದು\nಇದ್ದಂತೆ ನಾಳೆ ಇರದ],[ಅಶ್ವ*ತ್ಥ-ಕುದುರೆಯಂತೆ ನಿರಂತರ ಚಲನಶೀಲವಾದ] ಅರಳಿಯ ಮರ. ವೇದಗಳು\nಇದರ ಎಲೆಗಳು. ಇದನ್ನು ಬಲ್ಲವನು ವೇದಗಳನ್ನು ಬಲ್ಲವನು.\n\nಉಪನಿಷತ್ತಿನ ಸಾರವೇ ಭಗವದ್ಗೀತೆ ಎನ್ನುವುದಕ್ಕೆ ಈ ಶ್ಲೋಕವೇ ಸಾಕ್ಷೆ. ಕಠೋಪನಿಷತ್ತಿನಲ್ಲಿ ಹೀಗೆ ಹೇಳಿದ್ದಾರೆ:\n“ಊರ್ಧ್ವಮೂಲೋ ಅವಾಕ್‌ ಶಾಖಃ ಏಷೋ ಅಶ್ವತ್ಥಃ ಸನಾತನಃ” ಎಂದು. ಇಲ್ಲಿ ಅದನ್ನು “ಊರ್ಧ್ವಮೂಲಮ್‌\nಅಧಃ ಶಾಖಮ್‌ ಅಶ್ವತ್ಥಮ್‌ ಪ್ರಾಹುಃ ಅವ್ಯಯಮ್‌” ಎಂದು ಹೇಳಿದ್ದಾರೆ. ಇದು ವಿಷಯ ಗರ್ಭಿತವಾದ ಸಾಲು.\nಇಲ್ಲಿರುವ ಒಂದೊಂದು ಪದದಲ್ಲೂ ತತ್ವಶಾಸ್ತ್ರದ ಅನೇಕ ವಿಷಯಗಳು ಅಡಗಿವೆ.\n\nನೇರವಾಗಿ ಈ ಸಾಲನ್ನು ಕನ್ನಡಕ್ಕೆ ಭಾಷಾಂತರಿಸಿದರೆ “ಈ ವಿಶ್ವವೇ ಒಂದು ಅರಳಿ ಮರ. ಇದರ ಬುಡ\nಇರುವುದು ಮೇಲೆ, ಟೊಂಗೆ-ಟಿಸಿಲುಗಳಿರುವುದು ಕೆಳಗೆ” ಎಂದಾಗುತ್ತದೆ. ಮೇಲ್ನೋಟಕ್ಕೆ ಈ ಸಾಲನ್ನು\nನೋಡಿದರೆ ನಮಗೆ ಏನೂ ಅರ್ಥವಾಗುವುದಿಲ್ಲ. \"ಶೀರ್ಷಾಸನ ಮಾಡುತ್ತಿರುವ ಅರಳಿ ಮರ'- ಏನಿದು? ಅದರಲ್ಲೂ\nಅಶ್ವತ್ಥ ಮರವನ್ನೇ ಕೃಷ್ಣ ಏಕೆ ಹೇಳಿದ? ಹಣ್ಣನ್ನೂ ಕೊಡದ, ಹೂವನ್ನೂ ಬಿಡದ, ಮನೆಕಟ್ಟಲೂ ಸಹಾಯಕವಲ್ಲದ\nಈ",
  "15.1": "ಭಗವಾನ್‌ ಉವಾಚ-ಭಗವಂತ ಹೇಳಿದನು:\n\nಊರ್ಧ್ವಮೂಲಮ್‌ ಅಧಃ ಶಾಖಮ್‌ ಅಶ್ವತ್ಥಮ್‌ ಪ್ರಾಹುಃ ಅವ್ಯಯಮ್‌ |\n\nಛಂದಾಂಸಿ ಯಸ್ಯ ಪರ್ಣಾನಿ ಯಸ್ತಂ ವೇದ ಸಃ ವೇದವಿತ್‌ -ಮೇಲಿರುವ ಭಗವಂತ ಮತ್ತು ಪ್ರಕೃತಿ ವಿಶ್ವದ\nಬುಡಕಟ್ಟು. ಕೆಳಗಿನ ಜೀವ-ಜಡಗಳು ಇದರ ಟೊಂಗೆ-ಟಿಸಿಲು. ಇದು ಎಂದೆಂದೂ ಇರುವ, [ಅಶ್ವತ್ಥ - ಇಂದು\nಇದ್ದಂತೆ ನಾಳೆ ಇರದ], [ಅಶ್ವತ್ಥ-ಕುದುರೆಯಂತೆ ನಿರಂತರ ಚಲನಶೀಲವಾದ] ಅರಳಿಯ ಮರ. ವೇದಗಳು\nಇದರ ಎಲೆಗಳು. ಇದನ್ನು ಬಲ್ಲವನು ವೇದಗಳನ್ನು ಬಲ್ಲವನು.\n\nಉಪನಿಷತ್ತಿನ ಸಾರವೇ ಭಗವದ್ಗೀತೆ ಎನ್ನುವುದಕ್ಕೆ ಈ ಶ್ಲೋಕವೇ ಸಾಕ್ಷೆ. ಕಠೋಪನಿಷತ್ತಿನಲ್ಲಿ ಹೀಗೆ ಹೇಳಿದ್ದಾರೆ:\n“ಊರ್ಧ್ವಮೂಲೋ ಅವಾಕ್‌ ಶಾಖಃ ಏಷೋ ಅಶ್ವತ್ಥಃ ಸನಾತನಃ” ಎಂದು. ಇಲ್ಲಿ ಅದನ್ನು “ಊರ್ಧ್ವಮೂಲಮ್‌\nಅಧಃ ಶಾಖಮ್‌ ಅಶ್ವತ್ಥಮ್‌ ಪ್ರಾಹುಃ ಅವ್ಯಯಮ್‌” ಎಂದು ಹೇಳಿದ್ದಾರೆ. ಇದು ವಿಷಯ ಗರ್ಭಿತವಾದ ಸಾಲು.\nಇಲ್ಲಿರುವ ಒಂದೊಂದು ಪದದಲ್ಲೂ ತತ್ವಶಾಸ್ತ್ರದ ಅನೇಕ ವಿಷಯಗಳು ಅಡಗಿವೆ.\n\nನೇರವಾಗಿ ಈ ಸಾಲನ್ನು ಕನ್ನಡಕ್ಕೆ ಭಾಷಾಂತರಿಸಿದರೆ “ಈ ವಿಶ್ವವೇ ಒಂದು ಅರಳಿ ಮರ. ಇದರ ಬುಡ\nಇರುವುದು ಮೇಲೆ, ಟೊಂಗೆ-ಟಿಸಿಲುಗಳಿರುವುದು ಕೆಳಗೆ” ಎಂದಾಗುತ್ತದೆ. ಮೇಲ್ನೋಟಕ್ಕೆ ಈ ಸಾಲನ್ನು\nನೋಡಿದರೆ ನಮಗೆ ಏನೂ ಅರ್ಥವಾಗುವುದಿಲ್ಲ. \"ಶೀರ್ಷಾಸನ ಮಾಡುತ್ತಿರುವ ಅರಳಿ ಮರ'- ಏನಿದು? ಅದರಲ್ಲೂ\nಅಶ್ವತ್ಥ ಮರವನ್ನೇ ಕೃಷ್ಣ ಏಕೆ ಹೇಳಿದ? ಹಣ್ಣನ್ನೂ ಕೊಡದ, ಹೂವನ್ನೂ ಬಿಡದ, ಮನೆಕಟ್ಟಲೂ ಸಹಾಯಕವಲ್ಲದ\nಈ ಮರದ ಪ್ರಸ್ತಾಪ ಏಕೆ? ಇದು ಅರ್ಥವಾಗಬೇಕಾದರೆ ನಾವು 'ಅಶ್ವತ್ಥ' ಪದದ ಹಿಂದಿರುವ ಅರ್ಥವನ್ನು\nಹುಡುಕಬೇಕು. ಮೇಲ್ನೊ ೀಟದ ಅರ್ಥದಿಂದ ಒಂದೊಂದಾಗಿ ಎಳೆ-ಎಳೆಯಾಗಿ ಒಳಹೊಗಬೇಕು.\n\n(೧) ಅಶ್ವತ್ಥ ಅನ್ನುವುದಕ್ಕೆ ಸ್ಥೂಲ ಅರ್ಥ ಅರಳಿ ಮರ. ಪ್ರಪಂಚದಲ್ಲಿರುವ ಎಲ್ಲಾ ಮರಗಳಿಗಿಂತ ಈ ಮರ ಭಿನ್ನ.\nಗಾಳಿಯ ಸುಳಿಯೇ ಇಲ್ಲದೆ ಎಲ್ಲಾ ಮರಗಳೂ ಸ್ಥಬ್ಧವಾಗಿರುವಾಗ , ಸಣ್ಣ ಗಾಳಿಯ ಎಳೆ ಬಂದರೆ ಯಾವ ಮರವೂ\nಅಲ್ಲಾಡುವುದಿಲ್ಲ. ಆದರೆ ಅಶ್ವತ್ಥಮರದ ಎಲೆಗಳು ಗಿಲಿ-ಗಿಲಿ ಎಂದು ಹಂದಾಡಲು ಆರಂಭಿಸುತ್ತವೆ. ಅಶ್ವತ್ಥಕ್ಕೆ\nಸಂಸ್ಕೃತದಲ್ಲಿ “ಚಲದಲಃ' ಎಂದೂ ಕರೆಯುತ್ತಾರೆ. ಅಂದರೆ ಯಾವಾಗಲೂ ಚಲನಶೀಲವಾದ ಎಲೆಗಳುಳ್ಳ ಮರ\nಎಂದರ್ಥ. ಇದೇ ಪ್ರಪಂಚಕ್ಕೂ ಮತ್ತು ಅಶ್ವತ್ಛಮರಕ್ಕೂ ಇರುವ ಸಾಮ್ಯ. ಪ್ರಪಂಚ ಕೂಡಾ ಯಾವಾಗಲೂ\n\nಚಲನಶೀಲ. ಅದು ಸದಾ ಚಲಿಸುತ್ತಾ ಬದಲಾಗುತ್ತಾ ಇರುತ್ತದೆ.\n\n(೨) ಅಶ್ವತ್ಥ: ಇಲ್ಲಿ ಅಶ್ವ ಎಂದರೆ ಕುದುರೆ. ಪ್ರಪಂಚ ಅಶ್ವದ ಹಾಗೆ ಇರುವಂತಹದ್ದು. ಕುದುರೆಯನ್ನು\nಗಮನಿಸಿದರೆ ನಮಗೆ ಈ ಅರ್ಥ ತಿಳಿಯುತ್ತದೆ. ಇತರ ಪ್ರಾಣಿಗಳಿಗೂ ಕುದುರೆಗೂ ಒಂದು ವ್ಯತ್ಯಾಸವಿದೆ. ಎಲ್ಲಾ\nಪ್ರಾಣಿಗಳೂ ವಿಶ್ರಾಮದ ಕಾಲದಲ್ಲಿ ನಿಶ್ಚಲವಾಗಿ ನಿಲ್ಬಬಲ್ಲವು. ಆದರೆ ಕುದುರೆ ಒಂದು ಕ್ಷಣವೂ ನಿಶ್ಚಲವಾಗಿ\nನಿಲ್ಲದು. ಈ ಜಗತ್ತೂ ಕೂಡಾ ಅಶ್ವದಂತೆ. ಇದು ಎಂದೂ ಸ್ಥಿರವಾಗಿ ನಿಲ್ಲುವುದಿಲ್ಲ.\n\n(೩) ಅ-ಶ್ವಃ-ತ್ಥ -ಇಲ್ಲಿ 'ಶ್ವಃ' ಅಂದರೆ ನಾಳೆ, “ತ್ಥ' ಅಂದರೆ ಇರುವಂಥದ್ದು. ಅಶ್ವತ್ಥ ಅಂದರೆ “ನ ಶ್ವಃ ತಿಷ್ಠತಿ”.\nಇಂದು ಇದೆ ಆದರೆ ನಾಳೆ ಇರುತ್ತದೆ ಎನ್ನುವ ಖಾತರಿ ಇಲ್ಲ. ಅಂದರೆ ಈ ಪ್ರಪಂಚ ಕ್ಷಣಿಕ. ಕಠೋಪನಿಷತ್ತಿನಲ್ಲಿ\nಯಮ- ನಚಿಕೇತನಲ್ಲಿ “ನಿನಗೆ ಯಾವ ಸುಖಭೋಗ ಬೇಕಿದ್ದರೂ ಕೊಡುತ್ತೇನೆ” ಎಂದಾಗ, ನಚಿಕೇತ\nಹೇಳುತ್ತಾನೆ: “ಶ್ವೋಭಾವಾ ಮರ್ತ್ಯಸ್ಯ ಯದಂತಕ್ಕೆತತ್‌.. ಸರ್ವೇಂದ್ರಿಯಾಣಾಂ ಜರಯಂತಿ ತೇಜಃ”\nಎಂದು(೧-೨೬). “ಸದಾ ಬದಲಾಗುತ್ತಿರುವ ಕ್ಷಣಿಕವಾದ ಈ ಪ್ರಪಂಚದಲ್ಲಿ, ನಮ್ಮನ್ನು ಕಿತ್ತು ತಿನ್ನುವ ಭೋಗ\nನನಗೆ ಬೇಡ, ಬದಲಿಗೆ ಜ್ಞಾನವನ್ನು ಕೊಡು” ಎಂದು ನಚಿಕೇತ ಕೇಳುತ್ತಾನೆ. ಬದಲಾವಣೆಯೇ ಜಗದ ನಿಯಮ.\n(೪) ಅಶ್ವತ್ಥದ ಶಾಸ್ತ್ರೀಯ ನಿರ್ವಚನ ಅರ್ಥವನ್ನು ನೋಡಿದರೆ(etymological meaning)- ಅಶು-ವಾ-ತ-ಥ. ಇಲ್ಲಿ\nಅಶು-ವಾ ಎಂದರೆ ಎಲ್ಲಕ್ಕಿಂತ ವೇಗವಾಗಿ ಹೋಗುವಂತಹದ್ದು-ಅದು ಭಗವಂತ. ಅದಕ್ಕಾಗಿ ಭಗವಂತನನ್ನು\n\"ಅಶ್ವ' ಎಂದೂ ಕರೆಯುತ್ತಾರೆ. ಕುದುರೆ ಮುಖದ ಹಯಗ್ರೀವ ರೂಪದಲ್ಲಿ ಭಗವಂತ ಸಮಸ್ತ ವೇದ ವಿದ್ಯೆಯನ್ನು\nಪ್ರಪಂಚಕ್ಕೆ ಕೊಟ್ಟ. ಎಲ್ಲವನ್ನೂ ಎಲ್ಲಕ್ಕಿಂತ ಮೊದಲು ತಿಳಿದ ಭಗವಂತ ಈ ಜಗತ್ತಿನಲ್ಲಿ, ಇದರ ಒಳಗೂ\nಹೊರಗೂ ನಿಯಮನ ಮಾಡುವುದಕ್ಕೋಸ್ಕರ 'ಅಶ್ವ' ನಾಮಕನಾಗಿ ಕೂತಿದ್ದಾನೆ(ತ್ಥ). ಈತ ಇಡೀ ಪ್ರಪಂಚದಲ್ಲಿ\n'ತತ'(ತುಂಬಿದ್ದಾನೆ) ಮತ್ತು ಕೊನೆಗೆ ಇಡೀ ಜಗತ್ತು ಆತನಿಗೆ ಥಂ.(ಥಂ ಆಹಾರ -ಇಡೀ ಜಗತ್ತನ್ನು ಕಬಳಿಸುವ\nಶಕ್ತಿ, ಇದು ಪ್ರಳಯದ ವಿವರಣೆ).\n\nಇವು ನಾವು \"ಅಶ್ವತ್ಥ' ಎನ್ನುವ ಪದದಲ್ಲಿ ಕಾಣಬಹುದಾದ ಅರ್ಥ. ಈ ರೀತಿ ಒಂದು ಪದದಲ್ಲಿ ಅನೇಕ\nವಿಷಯಗಳನ್ನು ತುಂಬಿಸಲು ಬೇರೆ ಯಾವ ಭಾಷೆಯಲ್ಲೂ ಸಾಧ್ಯವಿಲ್ಲ. ಅದಕ್ಕಾಗಿ ಸಂಸ್ಕೃತವನ್ನು ಗರ್ಭಿಣಿ\n(ಅರ್ಥಗರ್ಭಿತ) ಭಾಷೆ ಎನ್ನುತ್ತಾರೆ. ಇಲ್ಲಿ ಹೇಳಿದ ಮರದ ಕಲ್ಪನೆ ಮತ್ತು ವಿವರಣೆ ಬೈಬಲ್‌ ನಲ್ಲಿ ಕೂಡಾ\nಕಾಣಬಹುದು. ಅಲ್ಲಿ ಅವರು ಮರಕ್ಕೆ “The Garden of Eden” ಎಂದಿದ್ದಾರೆ. ಅಲ್ಲಿ ಹೇಳುತ್ತಾರೆ: but of the tree of the knowledge of good and evil, you shall not eat of it; for in the day that you eat of it you will surely die.\" ಅಂದರೆ: “ಈ ಮರ ಹಣ್ಣು ಬಿಡುತ್ತದೆ; ಈ ಹಣ್ಣನ್ನು ತಿಂದರೆ ನೀನು ಸಾಯುತ್ತೀಯ” ಎಂದು. ಇಲ್ಲಿ\nಹಣ್ಣು ಅಂದರೆ ಅದು ಕರ್ಮಫಲ. ಕರ್ಮಫಲ ಅಪೇಕ್ಷೆ(desire for fruit) ಮಾಡುವವ ಸಾವಿಲ್ಲದ ಮೋಕ್ಷವನ್ನು\nಪಡೆಯಲಾರ. ಆತ ನಿರಂತರ ಹುಟ್ಟು ಸಾವಿನ ಚಕ್ರದಲ್ಲಿ ಸುತ್ತುತ್ತಾನೆ ಎನ್ನುವುದು ಈ ಸಾಲಿನ ಒಳಾರ್ಥ.\n“ಪ್ರಾಹುಃ ಅವ್ಯಯಮ್‌” ಎನ್ನುವಲ್ಲಿ 'ಪ್ರಾಹುಃ' ಎಂದರೆ ತಿಳಿದು ಹೇಳುವುದು. “ವೇದಕಾಲದ ಖುಷಿಗಳು ಈ\nಪ್ರಪಂಚ ಒಂದು ಅಶ್ವತ್ಥ ಎಂದು ತಿಳಿದು ಹೇಳಿದ್ದಾರೆ” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. “ಈ ಪ್ರಪಂಚ ನಶ್ವರ, ಒಂದು ದಿನ\nನಾಶವಾಗುವಂತಹದ್ದು” ಎಂದು ಹೇಳಿ, ತಕ್ಷಣ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ-“ಇದು ಅವ್ಯಯ” ಎಂದು! ಅಂದರೆ\nನಾಶವಿಲ್ಲದ್ದು! ಇದು ಅರ್ಥವಾಗಬೇಕಾದರೆ ನಾವು ಸಮುದ್ರ ತಡಿಯಲ್ಲಿ ಹೋಗಿ ಕುಳಿತು ಅಲ್ಲಿ ಬರುವ ತೆರೆಗಳನ್ನು\nಗಮನಿಸಬೇಕು. ಪ್ರತಿಯೊಂದು ತೆರೆಯೂ ಕೂಡಾ ಅಬ್ಬರದಿಂದ ಬರುತ್ತದೆ. ಅಲ್ಲಿ ಯಾವ ತೆರೆಯೂ ಶಾಶ್ವತವಲ್ಲ.\nಎಲ್ಲಾ ತೆರೆಯೂ ಕ್ಷಣಿಕ. ಆದರೆ ಸಮುದ್ರದಲ್ಲಿ ತೆರೆ ಇಲ್ಲದ ಕ್ಷಣವಿಲ್ಲ. ಅದು ಅವ್ಯಯ. ಅದೇ ರೀತಿ ಒಂದು ಪ್ರಪಂಚ\n\nನಾಶವಾಗುತ್ತದೆ, ಇನ್ನೊಂದು ಪ್ರಪಂಚ ಹುಟ್ಟುತ್ತದೆ. ಪ್ರಪಂಚ ನಾಶವಾಗಬಹುದು ಆದರೆ ಪ್ರಪಂಚದ ಪ್ರವಾಹ\nನಿರಂತರ. ಒಂದು ಪ್ರಳಯದ ನಂತರ ಇನ್ನೊಂದು ಸೃಷ್ಟಿ; ಸೃಷ್ಟಿಯ ನಂತರ ಪ್ರಳಯ-ಇದು ನಿರಂತರ.\nಆದ್ದರಿಂದ ಪ್ರಪಂಚ ಅವ್ಯಯ; ಜೀವ ಅನಾದಿ ಅನಂತ; ಹುಟ್ಟು ಸಾವು ನಿರಂತರ. ಜೀವ-ಜಡಗಳ ಸಮಾಗಮ\nಜನನ; ಅದರ ಬೇರ್ಪಡುವಿಕೆ ಮರಣ. ಇಲ್ಲಿ ಎಲ್ಲವೂ ನಿರಂತರ ಬದಲಾವಣೆಯನ್ನು ಕಾಣುತ್ತದೆ. ಒಟ್ಟಿನಲ್ಲಿ ಈ\nಜಗತ್ತು ಅಳಿವಿರದ ಅಶ್ವತ್ಥ.\nಇಲ್ಲಿ “ಈ ಮರದ ಮೂಲ ಮೇಲಿದೆ(ಊರ್ಧ್ವಮೂಲ)” ಎಂದಿದ್ದಾರೆ. ಮೇಲೆ ಅಂದರೆ ಎಲ್ಲಕ್ಕಿಂತ ಹಿರಿದಾದ\nಭಗವಂತ. ಈ ಪ್ರಪಂಚ ಅನ್ನುವ ಮರಕ್ಕೆ ಮೂಲ ಆ ಭಗವಂತ. ಪ್ರಪಂಚದ ಮೂಲದಲ್ಲಿ ಎಲ್ಲಕ್ಕಿಂತ ಎತ್ತರದಲ್ಲಿ\nತಂದೆ-ತಾಯಿಯಾಗಿ ಲಕ್ಷ್ಮೀ-ನಾರಾಯಣರಿದ್ದಾರೆ. ಜಡಪ್ರಕೃತಿಯಿಂದ ಈ ಮರ ವಿಕಸನವಾಗುತ್ತದೆ.\nಭಗವಂತನಿಂದ ಚತುರ್ಮುಖಬ್ರಹ್ಮ(ಮಹತತ್ವ), ವಾಯು, ಗರುಡ-ಶೇಷ-ರುದ್ರರು(ಆಹಂಕಾರ ತತ್ವ), ಇಂದ್ರಾದಿ\nದೇವತೆಗಳು, ಅವಾಂತರ ದೇವತೆಗಳು, ಗಂಧರ್ವರು, ಮನುಷ್ಯರು, ಪ್ರಾಣಿಗಳು, ಪಕ್ಷಿಗಳು, ಹೀಗೆ ಒಂದರ\nನಂತರ ಒಂದು ಶಾಖೆಗಳು ಸೃಷ್ಟಿ ಯಾದವು. ಇವೆಲ್ಲವೂ ಸೇರಿ ಒಂದು ಮರವಾಯಿತು. ಇಲ್ಲಿ \"ಅಧಃ ಶಾಖಮ್‌'\nಅಂದರೆ ಮೇಲಿನಿಂದ ಕೆಳಕ್ಕೆ ಬೆಳೆಯುವುದು. ಇದು ದೇವತಾ ತಾರತಮ್ಯವನ್ನು ಸೂಚಿಸುತ್ತದೆ.\nಮರದ ಟೊಂಗೆ-ಟಿಸಿಲಿನ ನಂತರ ಅದರ ಎಲೆಗಳು. “ಈ ಮರದ ಎಲೆಗಳೇ ವೇದಗಳು” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.\nನಮಗೆ ತಿಳಿದಂತೆ ಪ್ರಪಂಚಕ್ಕೆ ಎರಡು ಮುಖ. ಒಂದು ನಾಮಾತ್ಮಕ ಪ್ರಪಂಚ, ಇನ್ನೊಂದು ರೂಪಾತ್ಮಕ\nಪ್ರಪಂಚ. ಇಲ್ಲಿ ರೂಪಾತ್ಮಕ ಪ್ರಪಂಚ ಟೊಂಗೆ-ಟಿಸಿಲುಗಳಾದರೆ, ನಾಮಾತ್ಮಕ ಪ್ರಪಂಚ ಮರದ ಎಲೆ. ಮೊಟ್ಟ\nಮೊದಲು ನಾಮಾತ್ಮಕ ಪ್ರಪಂಚದಲ್ಲಿ ಸೃಷ್ಟಿಯಾದದ್ದು ವೇದಗಳು. ವಸ್ತುವಿಗೆ ಒಂದು ಹೆಸರು ಕೊಟ್ಟಿರುವುದು ಈ\nವೇದದಲ್ಲಿರುವ ವೈದಿಕ ಶಬ್ದಗಳು.\n\nಸರ್ವೇಷಾಂ ತ ಸ ನಾಮಾನಿ ಕರ್ಮಾಣಿ ಚ ಪೃಥಕ್‌ ಪೃಥಕ್‌\n\nವೇದಶಬ್ದೇಭ್ಯ ಏವಾದೌ ಪೃಥಕ್‌ ಸಂಸ್ಥಾಶ್ಚ ನಿರ್ಮಮೇ ॥ಮನುಸ್ಮೃತಿ ೧-೨೧॥\nವೇದದಲ್ಲಿ ಏನು ಶಬ್ದಗಳಿವಿಯೋ ಅವು ಮೂಲತಃ ಭಗವಂತನ ನಾಮಗಳು. ಅದನ್ನೇ ಲೋಕಕ್ಕೆ ಬಳಸಿದರು. ಈ\nರೀತಿ ಶಬ್ದಗಳ ಸೃಷ್ಟಿಯಾಯಿತು. ಅದೇ ಛಂದಸ್ಸು. ವೇದ ಮಂತ್ರಗಳು-ವೇದವಾಹ್ಮಯಗಳೇ ಈ ಮರದ\nಎಲೆಗಳು.\n\nಏಕೆ ವೇದವನ್ನು ಇಲ್ಲಿ ಎಲೆಗೆ ಹೋಲಿಸಿದರು ಎಂದರೆ, ಒಂದು ಮರ ಹೂ-ಹಣ್ಣು ಕೊಡಬೇಕಾದರೆ ಅಲ್ಲಿ\nಫಲಪ್ರದತ್ವ ಇರುವುದು ಎಲೆಗೆ. ಹಾಗೇ ನಮಗೆ ಅಧ್ಯಾತ್ಮ ಸಾಧನೆಯ ಫಲವನ್ನು ಕೊಡತಕ್ಕವು ವೇದಗಳು. ಈ\nಕಾರಣಕ್ಕಾಗಿ ಮರವನ್ನು ವಿಶ್ವಕ್ಕೆ ಹೋಲಿಸಿದರೆ, ಮರದ ಎಲೆಯನ್ನು ವೇದಗಳಿಗೆ ಹೋಲಿಸಿದ ಕೃಷ್ಣ.\nಪ್ರಳಯಕಾಲದಲ್ಲಿ ಮರ ನಾಶವಾಗುತ್ತದೆ. ಆದರೆ ಮರದ ಎಲೆ ನಾಶವಾಗುವುದಿಲ್ಲ. ಆದ್ದರಿಂದ “ಪ್ರಳಯ\nಕಾಲದಲ್ಲಿ ಭಗವಂತ ಆಲದ ಎಲೆಯ ಮೇಲೆ ಮಲಗಿರುತ್ತಾನೆ'-ಎನ್ನುತ್ತಾರೆ. ವೇದ ನಿತ್ಯ ಅದಕ್ಕೆ ನಾಶವಿಲ್ಲ.\nಎಲೆಯ ಮೇಲೆ ಭಗವಂತ ಮಲಗಿದ ಎಂದರೆ ವೇದ ವಾಚ್ಯನಾಗಿ ಮಲಗಿದ ಎಂದರ್ಥ. ಪ್ರಳಯಕಾಲದಲ್ಲಿ\nವೇದಗಳಿದ್ದವು ಎನ್ನುವುದು ಇದರಿಂದ ತಿಳಿಯುತ್ತದೆ. ಇಲ್ಲಿ ನಮಗೆ ಒಂದು ಪ್ರಶ್ನೆ ಬರಬಹುದು. ಯಾವ ವಸ್ತುವೂ\nಇಲ್ಲದೇ ಇದ್ದಾಗ ವೇದಗಳಿದ್ದವು ಅಂದರೆ ಏನು ಅರ್ಥ? ಅಗ್ನಿ ಮೀಳೇ ಪುರೋಹಿತಂ... ಎನ್ನು ವಲ್ಲಿ ಅಗ್ನಿ ಯೂ ಇಲ್ಲ,\n\nಪುರೋಹಿತನೂ ಇಲ್ಲ. ಹೀಗಿರುವಾಗ ಯಾರು ವೇದವನ್ನು ಹೇಳುವವರು ಮತ್ತು ವೇದಗಳು ಪ್ರಳಯ ಕಾಲದಲ್ಲಿ\nಯಾರನ್ನು ಹೇಳುತ್ತವೆ ?\n\nಪ್ರಳಯ ಕಾಲದಲ್ಲಿ ವೇದಗಳಿಗೆ ಭಗವಂತನೊಬ್ಬನೇ ಅರ್ಥ. ಇನ್ಯಾವ ಅರ್ಥವೂ ಇಲ್ಲ. ಹಾಗಾಗಿ ವೇದದಲ್ಲಿನ\nಸರ್ವ ಶಬ್ದವೂ ಭಗವಂತನನ್ನು ಹೇಳುತ್ತವೆ. “ನಾಮಾನಿ ಸರ್ವಾಣಿ ಯಮಾ ವಿಷಂತಿ ತಮ್‌ ವೈ ವಿಷ್ಣುಂ ಪರಮ\nಉದಾಹರಂತಿ”- ಯಾರಲ್ಲಿ ಎಲ್ಲಾ ಶಬ್ದಗಳು ಪ್ರವೇಶ ಮಾಡುತ್ತವೋ-ಅವನು ವಿಷ್ಣು. ಆತ ಸರ್ವ ಶಬ್ದವಾಚ್ಯ.\nವಿಷ್ಣು ಅಂದರೆ “ವಿಷಂತಿ ಸರ್ವಾಣಿ ನಾಮಾನಿ ಅತ್ರ”. ಐತರೇಯ ಅರಣ್ಯಕದಲ್ಲಿ ಹೇಳುವಂತೆ: “ಸರ್ವೇ\nಘೋಷಾಃ ಸರ್ವೇ ವೇದಾಃ ಸರ್ವಾಃ ರಚಃ ಎಕೈವ ವ್ಯಾಹೃತಿಃ...” ಪ್ರಕೃತಿಯಲ್ಲಿನ ಸರ್ವಶಬ್ದಗಳು, ಸರ್ವ\nನಾದಗಳು ಭಗವಂತನನ್ನು ಹೇಳುತ್ತವೆ. ಹೀಗಾಗಿ ಪ್ರಳಯ ಕಾಲದಲ್ಲಿ ವೇದಾಭಿಮಾನಿನಿ ಲಕ್ಷ್ಮಿ ವೇದವನ್ನು\nಹಾಡುತ್ತಿರುತ್ತಾಳೆ(ಶ್ರುತಿಗೀತ) ಮತ್ತು ಭಗವಂತ ಕೇಳುತ್ತಿರುತ್ತಾನೆ. ಇದು ನಾಮಾತ್ಮಕ ಪ್ರಪಂಚದ ಪರಿಕಲ್ಪನೆ.\nಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ಇಲ್ಲಿ ಹೇಳಿದ ವಿಚಾರವನ್ನು ಯಾರು ತಿಳಿಯುತ್ತಾರೋ ಅವರು ಸಮಸ್ತ ವೇದವನ್ನು\nತಿಳಿದಂತೆ” ಎಂದು.",
  "15.2": "ಅಧಃ ಚ ಊರ್ಧ್ವಂ ಪ್ರಸೃತಾಃ ತಸ್ಯ ಶಾಖಾಃ ಗುಣ ಪ್ರವೃದ್ಧಾಃ ವಿಷಯ ಪ್ರವಾಲಾಃ |\n\nಅಧಃ ಚ ಮೂಲಾನಿ ಅನುಸಂತತಾನಿ ಕರ್ಮ ಅನುಬಂಧೀನಿ ಮನುಷ್ಯಲೋಕೇ -- ತ್ರಿಗುಣಗಳಿಂದ ಕೊಬ್ಬಿದ ಇದರ ಟೊಂಗೆಗಳು ಕೆಳಗೂ ಮೇಲೂ ಹಬ್ಬಿ ಹರಡಿವೆ. ಇಂದ್ರಿಯ ವಿಷಯಗಳೇ ಇವುಗಳ ತಳಿರುಗಳು. ಇದರ ಬುಡಕಟ್ಟುಗಳು ಜೀವಿಗಳ ಕರ್ಮಕ್ಕೆ ತಕ್ಕಂತೆ ಕೆಳಗೆ ಕೂಡಾ, ಭೂಮಿಯಲ್ಲೂ ಹರಡಿಕೊಂಡಿವೆ.\n\nಮರದ ವರ್ಣನೆಯನ್ನು ಇಲ್ಲಿ ಮತ್ತಷ್ಟು ವಿವರಿಸಲಾಗಿದೆ. ಈ ಮರದ ಬೇರುಗಳು ಕೆಳಮುಖವಾಗಿಯೂ, ಮೇಲ್ಮುಖವಾಗಿಯೂ ಹರಡಿಕೊಂಡಿದೆ ಎನ್ನುವಲ್ಲಿ ಆಲದ ಮರದ ವರ್ಣನೆ ಎದ್ದು ಕಾಣುತ್ತದೆ. ಪಂಚಭೂತ ಎನ್ನುವ ಟೊಂಗೆ ಟೀಸಿಲು ಮೇಲಿನಿಂದ ಕೆಳಗಿನ ತನಕ ವ್ಯಾಪಿಸಿಕೊಂಡಿದೆ. ನಮ್ಮ ಶರೀರವನ್ನೇ ನೋಡಿದಾಗ- ನಮ್ಮ ಸಹಸ್ರಾರದಲ್ಲಿ ಭಗವಂತ ಕುಳಿತಿದ್ದಾನೆ. ಮೇಲಿನಿಂದ ಕೆಳಗಿನ ತನಕ ಪಂಚಭೂತಗಳು, ಸತ್ತ್ವ-ರಜಸ್ಸು- ತಮಸ್ಸು ಎನ್ನುವ ತ್ರಿಗುಣಗಳು ಟೊಂಗೆಗಳಾಗಿ ನಿಂತಿವೆ. ಇಲ್ಲಿ ಶಬ್ದ, ಸ್ಪರ್ಶ, ರೂಪ, ರಸ, ಗಂಧ ಚಿಗುರೆಲೆಗಳಿದ್ದಂತೆ. ಅಂದರೆ ಪಂಚಭೂತಾತ್ಮಕವಾದ ವಿಷಯಗಳೇ ಈ ಮರದ ಚಿಗುರು. ಈ ಚಿಗುರು ನಮಗೆ ಯಾವಾಗಲೂ ಆಕರ್ಷಣೆ. ಭಗವಂತನ ಅನಂತ ರೂಪ ಮೇಲಿನಿಂದ ಕೆಳಗಿನ ತನಕ ನಮ್ಮ ಅಂಗಾಂಗಗಳಲ್ಲಿ ತುಂಬಿದೆ. ಅಲ್ಲಿ ನಮ್ಮ ಕರ್ಮವನ್ನು ಅವಲಂಬಿಸಿ ಅವನ ಕ್ರಿಯೆ. ಭಗವಂತನ ಮೂಲ ಮೇಲೆ, ಆದರೆ ಆತ ಮೇಲಿನಿಂದ ಕೆಳಗಿನ ತನಕ ಹರಡಿಕೊಂಡಿದ್ದಾನೆ. ಹೀಗೆ ಆತ ಎಲ್ಲಾ ಕಡೆ ವ್ಯಾಪಿಸಿ ನಿಂತಿದ್ದಾನೆ.",
  "15.3": "ನ ರೂಪಮ್‌ ಅಸ್ಯ ಇಹ ತಥಾ ಉಪಲಭ್ಯತೇ ನಅಂತಃ ನಚ ಆದಿಃನಚ ಸಂಪ್ರತಿಷ್ಠಾ ।\n\nಅಶ್ವತ್ಥಮ್‌ ಏನಮ್‌ ಸು ವಿರೂಢ ಮೂಲಮ್‌ ಅಸಂಗಶಸ್ತ್ರೇಣ ದೃಢೇನ ಛಿತ್ತ್ವಾ -- ಇದರ ಇರುವು ಇದ್ದ ಹಾಗೆ ಕಾಣಿಸುವುದಿಲ್ಲ. ಇದರ ಕೊನೆ ಕಾಣದು; ಬುಡ ಕಾಣದು; ನೆಲೆ ಕೂಡಾ. ಬಲವಾಗಿ ಬೇರೂರಿದ ಈ ಅರಳಿಯನ್ನು ಅನಾಸಕ್ತಿಯೆಂಬ ಹರಿತವಾದ ಕತ್ತಿಯಿಂದ ತರಿದು...\n\nವಿಶ್ವವನ್ನು ಇಲ್ಲಿ ವಿವರಿಸಿದಷ್ಟು ಸ್ಪಷ್ಟವಾಗಿ ಎಲ್ಲಿಯೂ ವರ್ಣಿಸಿಲ್ಲ. ಇತರೆಡೆ ಸ್ವಲ್ಪ ಸ್ವಲ್ಪ ವಿವರಣೆ ಕಾಣಬಹುದು. ಆದರೆ ಕೃಷ್ಣ ಇಲ್ಲಿ ಪೂರ್ಣ ವಿವರಣೆ ಕೊಟ್ಟ. ಇಷ್ಟು ವಿವರಿಸಿದ ಮೇಲೆ ಕೃಷ್ಣ ಒಂದು ಎಚ್ಚರವನ್ನು ಕೊಡುತ್ತಾನೆ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಈ ಪ್ರಪಂಚದಲ್ಲೇ ಇದ್ದು ಪ್ರಪಂಚವನ್ನು ನೋಡಿದರೆ ನಾನು ವರ್ಣಿಸಿದ ಅಖಂಡ ದರ್ಶನ ಸಾಧ್ಯವಿಲ್ಲ” ಎಂದು. ನಮಗೆ ಯಾವ ವಸ್ತುವನ್ನು ಕೂಡಾ ಪರಿಪೂರ್ಣವಾಗಿ ಸಮಗ್ರವಾಗಿ ತಿಳಿದುಕೊಳ್ಳಲು ಆಗುವುದೇ ಇಲ್ಲ. ಏಕೆಂದರೆ ಇಡೀ ವಿಶ್ವವನ್ನು ತಿಳಿಯದೆ ವಿಶ್ವದ ಒಂದು ಚಿಕ್ಕ ಕಣ ಅರ್ಥವಾಗದು. ಸಮುದ್ರದ ತೀರದಲ್ಲಿನ ಒಂದು ಕಪ್ಪೆ ಸಮುದ್ರದ ಆಳ-ಅಗಲ ಮತ್ತು ಸಮುದ್ರದ ಅಗಾಧತೆಯನ್ನು ಹೇಗೆ ತಿಳಿಯಲಾರದೋ, ಹಾಗೇ ನಾವು ಈ ಪ್ರಪಂಚವನ್ನು ಪೂರ್ಣ ತಿಳಿಯಲು ಸಾಧ್ಯವಿಲ್ಲ.",
  "15.4": "ತತಃ ಪದಂ ತತ್‌ ಪರಿಮಾರ್ಗಿತವ್ಯಮ್‌ ಯಸ್ಮಿನ್‌ ಗತಾಃ ನ ನಿವರ್ತಂತಿ ಭೂಯಃ |\n\nತಮ್‌ ಏವ ಚ ಆದ್ಯಮ್‌ ಪುರುಷಮ್‌ ಪ್ರಪದ್ಯೇ ಯತಃ ಪ್ರವೃತ್ತಿಃ ಪ್ರಸೃತಾ ಪುರಾಣೀ -- ಅನಂತರ ಆ ಪರತತ್ವವನ್ನು ಅರಸಬೇಕು. ಅವನನ್ನು ಸೇರಿದವರು ಮತ್ತೆ ಮರಳುವುದಿಲ್ಲ. ಅವನಿಂದಲೇ ಈ ಪುರಾತನವಾದ ಪಯಣ ಪ್ರಾರಂಭವಾಯಿತು. ಎಲ್ಲದರ ಮೊದಲಿರುವ ಆ ಪರಮ ಪುರುಷನಿಗೇ ಶರಣಾಗಬೇಕು.\n\nವಿಶ್ವವನ್ನು ಇಲ್ಲಿ ವಿವರಿಸಿದಷ್ಟು ಸ್ಪಷ್ಟವಾಗಿ ಎಲ್ಲಿಯೂ ವರ್ಣಿಸಿಲ್ಲ. ಇತರೆಡೆ ಸ್ವಲ್ಪ ಸ್ವಲ್ಪ ವಿವರಣೆ ಕಾಣಬಹುದು. ಆದರೆ ಕೃಷ್ಣ ಇಲ್ಲಿ ಪೂರ್ಣ ವಿವರಣೆ ಕೊಟ್ಟ. ಇಷ್ಟು ವಿವರಿಸಿದ ಮೇಲೆ ಕೃಷ್ಣ ಒಂದು ಎಚ್ಚರವನ್ನು ಕೊಡುತ್ತಾನೆ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಈ ಪ್ರಪಂಚದಲ್ಲೇ ಇದ್ದು ಪ್ರಪಂಚವನ್ನು ನೋಡಿದರೆ ನಾನು ವರ್ಣಿಸಿದ ಅಖಂಡ ದರ್ಶನ ಸಾಧ್ಯವಿಲ್ಲ” ಎಂದು. ನಮಗೆ ಯಾವ ವಸ್ತುವನ್ನು ಕೂಡಾ ಪರಿಪೂರ್ಣವಾಗಿ ಸಮಗ್ರವಾಗಿ ತಿಳಿದುಕೊಳ್ಳಲು ಆಗುವುದೇ ಇಲ್ಲ. ಏಕೆಂದರೆ ಇಡೀ ವಿಶ್ವವನ್ನು ತಿಳಿಯದೆ ವಿಶ್ವದ ಒಂದು ಚಿಕ್ಕ ಕಣ ಅರ್ಥವಾಗದು. ಸಮುದ್ರದ ತೀರದಲ್ಲಿನ ಒಂದು ಕಪ್ಪೆ ಸಮುದ್ರದ ಆಳ-ಅಗಲ ಮತ್ತು ಸಮುದ್ರದ ಅಗಾಧತೆಯನ್ನು ಹೇಗೆ ತಿಳಿಯಲಾರದೋ, ಹಾಗೇ ನಾವು ಈ ಪ್ರಪಂಚವನ್ನು ಪೂರ್ಣ ತಿಳಿಯಲು ಸಾಧ್ಯವಿಲ್ಲ.",
  "15.5": "ನಿರ್ಮಾನಮೋಹಾಃ ಜಿತ ಸಂಗ ದೋಷಾಃ ಅಧ್ಯಾತ್ಮ ನಿತ್ಯಾಃ ವಿನಿವೃತ್ತಕಾಮಾಃ |\n\nದ್ವಂದ್ವೈಃ ವಿಮುಕ್ತಾಃ ಸುಖ ದುಃಖ ಸಂಜ್ಞೈಃ ಗಚ್ಛಂತಿ ಅಮೂಢಾಃ ಪದಮ್‌ ಅವ್ಯಯಮ್‌ ತತ್‌--ಬಿಂಕವಿರದವರು,\nಮೋಹವಳಿದವರು, ಬಯಕೆಗಳನ್ನು ಬಿಟ್ಟವರು, ಸುಖ-ದುಃಖಗಳೆಂಬ ಇಕ್ಕಟ್ಟಿನ ಇರುಕನ್ನು ಮೀರಿ ನಿಂತವರು-\nಇಂತಹ ಜಾಣರು ಈ ಅಳಿವಿರದ ತಾಣವನ್ನು ಸೇರುತ್ತಾರೆ.\n\nಕೃಷ್ಣ ಈ ಶ್ಲೋಕದಲ್ಲಿ ಹೇಳಿರುವ ವಿಚಾರ ಈ ಹಿಂದಿನ ಅನೇಕ ಅಧ್ಯಾಯಗಳಲ್ಲಿ ಅಲ್ಲಲ್ಲಿ ಬಂದಿದೆ ಮತ್ತು ಬಂದಾಗ\nನಾವು ಆ ಬಗ್ಗೆ ವಿಶೇಷವಾಗಿ ವಿಶ್ಲೇಷಣೆ ಮಾಡಿದ್ದೇವೆ. ಎಲ್ಲವನ್ನು ಸಮಷ್ಟಿಯಾಗಿ ಇಲ್ಲಿ ಕೃಷ್ಣ ಹೇಳಿದ್ದಾನೆ.\nಭಗವಂತನಲ್ಲಿ ಶರಣಾಗತಿ ಬೇಡಿ ಸಾಗುವ ನಮ್ಮ ಜೀವನದ ನಡೆ ಹೇಗಿರಬೇಕು ಎನ್ನುವುದನ್ನು ಈ ಶ್ಲೋಕದಲ್ಲಿ\nವಿವರಿಸಲಾಗಿದೆ. “ಎಲ್ಲಕ್ಕಿಂತ ಮೊದಲು ಮಾನ-ಮೋಹವನ್ನು ಬಿಡಬೇಕು” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಅಂದರೆ 'ನಾನು'\nಎನ್ನುವ \"ಅಹಂಕಾರ' ಮತ್ತು 'ನನ್ನದು' ಎನ್ನುವ “ಮಮಕಾರ' ಇವೆರಡನ್ನು ನಾವು ಮೊದಲು ತೊರೆಯಬೇಕು. ಈ\nಪ್ರಪಂಚಕ್ಕೆ ಬರುವಾಗಲೂ ನಾವು ಬತ್ತಲೆ, ಹೋಗುವಾಗಲೂ ಬತ್ತಲೆ. ಹೀಗಿರುವಾಗ ಇಲ್ಲಿ 'ನಾನು', “ನನ್ನ ದು'\nಎಂದು ಅಹಂಕಾರ-ಮಮಕಾರದಲ್ಲಿ ಬೀಳುವುದರಲ್ಲಿ ಯಾವುದೇ ಅರ್ಥವಿಲ್ಲ. ಸಂಗದೋಷ ನಮ್ಮ ಮೇಲೆ ಅನೇಕ\nಕೆಟ್ಟ ಪರಿಣಾಮವನ್ನು ಬೀರುತ್ತದೆ. ಅದಕ್ಕಾಗಿ ನಾವು ಸಂಗದೋಷವನ್ನು ಗೆಲ್ಲಬೇಕು. ಒಂದು ವಸ್ತುವಿನ\nಅತಿಯಾದ ಒಡನಾಟ, ಅದರ ಮೇಲಿನ ಅತಿಯಾದ ಮಮಕಾರ ಎಂದೆಂದಿಗೂ ಒಳ್ಳೆಯದಲ್ಲ. ಈ ರೀತಿ\nನಿರ್ಲಿಪ್ತತೆಯಿಂದ. ಬದುಕಬೇಕಾದರೆ. ಮೊದಲು. ನಮ್ಮನ್ನು ನಾವು. ಅಧ್ಯಾತ್ಮ ಚಿಂತನೆಯಲ್ಲಿ\nತೊಡಗಿಸಿಕೊಳ್ಳಬೇಕು. ಬಯಕೆಗಳನ್ನು ಬಿಟ್ಟು, ಸುಖ ಬಂದಾಗ ಹಾರಾಡದೇ, ದುಃಖ ಬಂದಾಗ ಕುಗ್ಗದೇ,\nದ್ವಂದ್ವಾತೀತರಾಗಿ ಬದುಕುವುದನ್ನು ನಾವು ಕಲಿಯಬೇಕು. ಸೋಲೇ ಗೆಲುವಿನ ಮೆಟ್ಟಿಲು, ದುಃಖ-ಸುಖದ\nಮೆಟ್ಟಿಲು. ಹಗಲು-ರಾತ್ರಿಯನ್ನು ಸ್ವೀಕರಿಸಿದಂತೆ ಕಷ್ಟ-ಸುಖವನ್ನು ನಾವು ಸಮನಾಗಿ ಸ್ವೀಕರಿಸಬೇಕು. ಲೌಕಿಕ\nನಿರೀಕ್ಷೆ-ನಿರಾಶೆಯ ಮೂಲ. ಇದರ ಹಿಂದೆ ಹೋದವರು ತಿಳಿಗೇಡಿಗಳು. ಅವರು ತಾವೇ ತಾವಾಗಿ ತಮ್ಮ\nಜೀವನದಲ್ಲಿ ಸಮಸ್ಯೆಯನ್ನು ತಂದುಕೊಳ್ಳುತ್ತಾರೆ. ಆದರೆ ಈ ಮರ್ಮವನ್ನು ಅರಿತ ಜ್ಞಾನಿಗಳು ಭಗವಂತನ\nಲೋಕವನ್ನು ನಿರಾಯಾಸವಾಗಿ ಸೇರುತ್ತಾರೆ-ಇದು ನಿಶ್ಚಿತ.\n\nದೇವರ ಬಗ್ಗೆ ದೇವರನ್ನು ನಂಬುವವರಲ್ಲೇ ಅನೇಕ ಅಭಿಪ್ರಾಯ ಭೇದಗಳಿವೆ. ಪ್ರತಿಯೊಬ್ಬರಿಗೂ ತಮ್ಮ\nವಿಚಾರಧಾರೆಯೇ ಸರಿ ಎನ್ನುವ ಭಾವನೆ ಇರುತ್ತದೆ. ಇದಕ್ಕಾಗಿ ಮುಂದಿನ ಶ್ಲೋಕಗಳಲ್ಲಿ ಕೃಷ್ಣ ಈ ಕುರಿತ\nವಿವರಣೆಯನ್ನು ಕೊಡುತ್ತಾನೆ. ಇಲ್ಲಿ ಪ್ರಸ್ತುತವಿರುವ ಶ್ಲೋಕಗಳಲ್ಲಿ ಇರುವ ವಿಚಾರ ನಮಗೆ ಸ್ವಲ್ಪ ಅಸ್ಪಷ್ಟವಾಗಿ\nಕಾಣಬಹುದು. ನಮ್ಮ ಸಾಧನೆ ಮತ್ತು ನಮ್ಮ ಯೋಗ್ಯತೆಗನುಗುಣವಾಗಿ ಈ ಶ್ಲೋಕಗಳು ತೆರೆದುಕೊಳ್ಳುತ್ತವೆ.\nಇಲ್ಲಿ ಕೃಷ್ಣ ಜೀವ-ಜಗತ್ತು-ಭಗವಂತ ಈ ತ್ರಿಪುಟಿಗಳ ಕಲ್ಪನೆಯನ್ನು ಬಹಳ ರೋಚಕವಾಗಿ ವಿವರಿಸಿದ್ದಾನೆ.\n\nಭಗವಂತನ ಚಿಂತನೆಯಲ್ಲಿ ಕಾಳಜಿ ಇರುವವರಿಗೆ ಈ ಅಧ್ಯಾಯದ ಮುಂದಿನ ಭಾಗ ಬಹಳ ಮುಖ್ಯವಾಗುತ್ತದೆ.\nನಮ್ಮ ಜೀವನದಲ್ಲಿ ನಾವು ಹೇಗೆ ಸಾಧನೆ ಮಾಡಬೇಕು, ಹೇಗೆ ಭಗವಂತನ ಚಿಂತನೆ ಮಾಡಬೇಕು ಅನ್ನುವುದರ\nಸಮಸ್ತ ಸಾರವನ್ನು ಕೃಷ್ಣ ಇಲ್ಲಿ ವಿವರಿಸಿದ್ದಾನೆ.",
  "15.6": "ನ ತತ್‌ ಭಾಸಯತೇ ಸೂರ್ಯಃ ನ ಶಶಾಂಕಃ ನ ಪಾವಕಃ ।\nಯತ್‌ ಗತ್ವಾ ನ ನಿವರ್ತಂತೇ ತತ್‌ ಧಾಮ ಪರಮಮ್‌ ಮಮ- ಅದನ್ನು ಸೂರ್ಯ ಬೆಳಗಿಸಲಾರ; ಚಂದ್ರ\nಬೆಳಗಿಸಲಾರ; ಬೆಂಕಿ ಕೂಡಾ. ಅದರತ್ತ ತೆರಳಿದವರು ಮತ್ತೆ ಮರಳುವುದಿಲ್ಲ. ಅದು ನನ್ನ ಹಿರಿಯ ರೂಪ.\n\nಇದೇ ರೀತಿಯ ವಿವರಣೆ ಕಠೋಪನಿಷತ್ತಿನಲ್ಲಿ ಬಂದಿದೆ. ಅದರ ಸಾರವನ್ನು ಕೃಷ್ಣ ಇಲ್ಲಿ ಹೇಳಿದ್ದಾನೆ.\nಕಠೋಪನಿಷತ್ತಿನಲ್ಲಿ ಹೇಳುವಂತೆ:\n\nನ ತತ್ರ ಸೂರ್ಯೋ ಭಾತಿ ನ ಚಂದ್ರತಾರಕಂ ನೇಮಾ ವಿದ್ಯುತೋ ಭಾಂತಿ ಕುತೋಽಯಮಗ್ನಿಃ ।\n\nತಮೇವ ಭಾಂತಮನುಭಾತಿ ಸರ್ವಂ ತಸ್ಯ ಭಾಸಾ ಸರ್ವಮಿದಂ ವಿಭಾತಿ ॥೧೫॥\n“ಭಗವಂತನನ್ನು ಸೂರ್ಯ ಬೆಳಗಿಸುವುದಿಲ್ಲ, ಬೆಳದಿಂಗಳಾಗಲೀ, ಅಗ್ನಿಯ ಬೆಳಕಾಗಲೀ ಆತನನ್ನು\nಬೆಳಗಿಸಲಾರದು” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಇಲ್ಲಿ ನಾವು ಉಪಾಸನೆ ಮಾಡುವ ಭಗವಂತನ ಪ್ರತೀಕವನ್ನು ಕೃಷ್ಣ\nಉದಾಹರಣೆಯಾಗಿ ತೆಗೆದುಕೊಂಡಿದ್ದಾನೆ. ನಾವು ಸೂರ್ಯನಲ್ಲಿ ಗಾಯತ್ರಿಯನ್ನು ಉಪಾಸನೆ ಮಾಡುತ್ತೇವೆ;\nಚಂದ್ರಮಂಡಲ ಮಧ್ಯಸ್ಥನಾಗಿ ಭಗವಂತನನ್ನು ಧನ್ವಂತರಿಯಲ್ಲಿ ಪೂಜಿಸುತ್ತೇವೆ; ಭೂಲೋಕದಲ್ಲಿ ಭಗವಂತನ\nಆರಾಧನೆ ಅಗ್ನಿ ಮುಖದಲ್ಲಿ. ಇಲ್ಲಿ ಕೃಷ್ಣ ಕೊಡುತ್ತಿರುವ ಎಚ್ಚರ ಏನೆಂದರೆ -ಇವೆಲ್ಲವೂ ಬೆಳಕಿನ ಪ್ರತೀಕ ಮಾತ್ರ.\nಇವು ನೇರವಾಗಿ ನಮಗೆ ಭಗವಂತನನ್ನು ತೋರಿಸಲಾರವು. ಭಗವಂತನನ್ನು ಕಾಣಲು ನಾವು ನಮ್ಮೊಳಗಿನ\nಸ್ವರೂಪಭೂತವಾದ ಅಂತಃಜ್ಯೋತಿಯನ್ನು ಬಳಸಬೇಕು. ಬೃಹದಾರಣ್ಯಕ ಉಪನಿಷತ್ತಿನಲ್ಲಿ(A-04) ಜನಕ\nಮತ್ತು ಯಾಜ್ಞವಲ್ಕ್ಯರ ನಡುವಿನ ಸಂಭಾಷಣೆಯಲ್ಲಿ ಈ ವಿಷಯವನ್ನು ಸ್ಪಷ್ಟವಾಗಿ ತೆರೆದಿಡಲಾಗಿದೆ:\nಯಾಜ್ಞವಲ್ಕ್ಯ, ಕಿಮ್‌ ಜ್ಯೋತಿರಯಂಪುರುಷಃ ಇತಿ | ಆದಿತ್ಯ ಜ್ಯೋತಿಃ, ಸಮ್ರಾಡ್‌,.. ॥೪-೨॥ -ಇಲ್ಲಿ ಜನಕ\nಯಾಜ್ಞವಲ್ಯ್ಯನಲ್ಲಿ ಕೇಳುತ್ತಾನೆ: “ಈ ಪ್ರಪಂಚದಲ್ಲಿ ಜೀವರು ತಮ್ಮ ಕಾರ್ಯ ನಿರ್ವಹಣೆ ಮಾಡಲು\nಸಹಾಯಕವಾದ ಬೆಳಕು ಯಾವುದು” ಎಂದು. ಇದಕ್ಕೆ ನೇರವಾಗಿ ಯಾಜ್ಞವಲ್ಕ್ಯ ಉತ್ತರಿಸುತ್ತಾನೆ “ ಸೂರ್ಯನ\nಪ್ರಕಾಶ” ಎಂದು.\nಅಸ್ತಮಿತ ಆದಿತ್ಯೇ ಯಾಜ್ಞವಲ್ಕ್ಯ, ಕಿಮ್‌ ಜ್ಯೋತಿರೇವಾಯಂ ಪುರುಷಃ ಇತಿ | ಚಂದ್ರಮೇವಾಸ್ಯ ಜ್ಯೋತಿರ್‌\nಭವತಿ, ..೪-೩॥ -ಸೂರ್ಯ ಪ್ರಕಾಶ ಇಲ್ಲದೇ ಇದ್ದಾಗ ಜೀವರು ಯಾವ ಬೆಳಕಿನಿಂದ ತಮ್ಮ ಕಾರ್ಯ ನಿರ್ವಹಣೆ\nಮಾಡುತ್ತಾರೆ ಎಂದಾಗ-ಯಾಜ್ಞವಲ್ಕ್ಯ ಹೇಳುತ್ತಾನೆ: “ಚಂದ್ರನ ಬೆಳಕಿನಿಂದ” ಎಂದು.\nಅಸ್ತಮಿತ ಆದಿತ್ಯೇ, ಯಾಜ್ಞವಲ್ಕ್ಯ,ಚಂದ್ರಮಸ್ಯಸ್ತಮಿತೇ, ಕಿಮ್‌ ಜ್ಯೋತಿರೇವಾಯಂ ಪುರುಷ ಇತಿ | ಅಗ್ನಿರೇವಾಸ್ಯ ಜ್ಯೋತಿರ್ಭವತಿ, ...೪-೪॥. ಸೂರ್ಯ ಚಂದ್ರ ಇಲ್ಲದಾಗ ಯಾವ ಬೆಳಕು ಎನ್ನುವ ಪ್ರಶ್ನೆಗೆ\nಯಾಜ್ಞವಲ್ಕ್ಯ ಉತ್ತರಿಸುತ್ತಾನೆ: “ಬೆಂಕಿಯ ಪ್ರಕಾಶದಿಂದ” ಎಂದು.\nಅಸ್ತಮಿತ ಆದಿತ್ಯೇ, ಯಾಜ್ಞವಲ್ಕ್ಯ,ಚಂದ್ರಮಸಿ ಅಸ್ತಮಿತೇ,ಶಾಂತೇಽಗ್ನೌ ಕಿಂಜ್ಯೋತಿರೇವಾಯಂ ಪುರುಷ\nಇತಿ | ವಾಗ್‌ ಎವಾಸ್ಯ ಜ್ಯೋತಿರ್‌ ಭವತಿ ವಾಚೈವಾಯಂ ಜ್ಯೋತಿಷಾಸ್ತೇ ಪಲ್ಯಯತೇ ಕರ್ಮ ಕುರುತೇ\nವಿಪಲ್ಯಯೇತಿ ತಸ್ಮಾದ್ದೈಕ, ಸಮ್ರಾಡ್, ಅಪಿ ಯತ್ರ ಪಾಣಿರ್ನ ವಿನಿರ್ಜಾಯತೇ, ಅಥ ಯತ್ರ ವಾಗುಚ್ಚರತಿ ಉಪೈವ ತತ್ರ ನ್ಯೇತೀತಿ | ಏವಮೇವೈತದ್‌ ಯಾಜ್ಞವಲ್ಕ್ಯ॥೪-೫॥ -ಒಂದು ವೇಳೆ ಸೂರ್ಯ, ಚಂದ್ರ, ಬೆಂಕಿ,\n\nನಕ್ಷತ್ರ- ಯಾವುದೇ ಬೆಳಕು ಇಲ್ಲದಾಗ ಜನರು ಹೇಗೆ ವ್ಯವಹರಿಸುತ್ತಾರೆ ಎಂದಾಗ ಯಾಜ್ಞವಲ್ಕ್ಯ ಉತ್ತರಿಸುತ್ತಾನೆ\n:“ಒಬ್ಬರಿಗೊಬ್ಬರು ಮಾತನಾಡುವ ಮೂಲಕ” ಎಂದು.\n\nಅಸ್ತಮಿತ ಆದಿತ್ಯೇ :ಯಾಜ್ಞವಲ್ಕ್ಯ,ಚಂದ್ರಮಸ್ಯಸ್ತಮಿತೇ, ಶಾಂತೇಽಗ್ನೌ, ಶಾಂತಾಯಾಂ ವಾಚಿ, ಕಿಮ್‌\nಜ್ಯೋತಿರೇವಾಯಂ ಪುರುಷ ಇತಿ | ಆತ್ಮೈವಾಸ್ಯ ಜ್ಯೋತಿರ್ಭವತಿ, ಆತ್ಮನೈವಾಯಂ ಜ್ಯೋತಿಷಾಸ್ತೇ\nಪಲ್ಯಯತೇ ಕರ್ಮ ಕುರುತೇ ವಿಪಲ್ಯಯೇತ್‌ ಇತಿ ॥೪-೬॥ ಎಲ್ಲಾ ಬೆಳಕೂ ಇಲ್ಲದಾಗ, ಯಾರೂ ಜೊತೆಯಲ್ಲಿ\nಇಲ್ಲದಾಗ ಯಾವ ಬೆಳಕು ನಮಗೆ ಶಕ್ತಿ ಎನ್ನುವ ಪ್ರಶ್ನೆಗೆ ಯಾಜ್ಞವಲ್ಕ್ಯ ಉತ್ತರಿಸುತ್ತಾನೆ “ಆತ್ಮ ಜ್ಯೋತಿ” ಎಂದು.\nಮೇಲ್ನೋಟಕ್ಕೆ ಈ ಸಂಭಾಷಣೆಯನ್ನು ನೋಡಿದರೆ ನಮಗೆ ಏನೂ ತಿಳಿಯುವುದಿಲ್ಲ. ಆದರೆ ಇದರಲ್ಲಿ ಪ್ರಾಚೀನರು\nಅದೆಷ್ಟು ವಿಚಾರವನ್ನು ತುಂಬಿದ್ದಾರೆ. ನಾವು ನಮ್ಮ ಅಂತರಂಗದಲ್ಲಿನ ಆತ್ಮಜ್ಯೋತಿಯ ಪರಿಚಯವಿಲ್ಲದೆ ಕೇವಲ\nಹೊರ ಪ್ರಪಂಚದಲ್ಲಿ ಭೌತಿಕ ಬೆಳಕಿನಲ್ಲಿ ಭಗವಂತನನ್ನು ಹುಡುಕುವುದರಿಂದ ಆತ ನಮಗೆ ಸಿಗಲಾರ. ಆತನನ್ನು\nಯಾವ ಭೌತಿಕ ಬೆಳಕೂ ಬೆಳಗಲಾರದು. ಆತ ಬೆಳಕುಗಳ ಬೆಳಕು. ಆತನನ್ನು ಕಾಣಲು ನಾವು ನಮ್ಮ\nಸ್ವರೂಪದಲ್ಲಿನ ಆತ್ಮಜ್ಯೋತಿಯನ್ನು ಬಳಸಬೇಕು. ಸೂರ್ಯ, ಚಂದ್ರ, ಅಗ್ನಿಯನ್ನು ಭಗವಂತನ ಪ್ರತೀಕವಾಗಿ\nಬಳಸಿ ನಮ್ಮ ಅಂತರಂಗದ ಜ್ಯೋತಿಯನ್ನು ನಾವು ಜಾಗೃತಗೊಳಿಸಿಕೊಳ್ಳಬೇಕು.\n\nಯಾವ ಸ್ಥಾನದಲ್ಲಿ ಭಗವಂತ ಸದಾ ಜ್ಞಾನಿಗಳಿಗೆ ಗೋಚರವಾಗುತ್ತಾನೋ ಅದು “ಪರಮಧಾಮ” ಅದೇ ಮೋಕ್ಷ.\nಅಲ್ಲಿ ಸೂರ್ಯನಾಗಲೀ, ಚಂದ್ರನಾಗಲೀ, ಅಗ್ನಿಯಾಗಲೀ ಬೆಳಕಲ್ಲ. ಈ ಪರಮಧಾಮದಿಂದಲೇ ಸೂರ್ಯ, ಚಂದ್ರ,\nಅಗ್ನಿ ಬೆಳಕು ಪಡೆಯುವುದು. ಆತ್ಮಜ್ಯೋತಿಯನ್ನು ಗುರುತಿಸಿ, ಆತ್ಮದಲ್ಲಿನ ಪರಮಾತ್ಮನನ್ನು ಕಂಡುಕೊಂಡವ\nಎಂದೂ ಮರಳಿಬಾರದ ಈ ಪರಮಧಾಮವನ್ನು ಸೇರುತ್ತಾನೆ.",
  "15.7": "ಮಮ ಏವ ಅಂಶಃ ಜೀವಲೋಕೇ ಜೀವಭೂತಃ ಸನಾತನಃ |\nಮನಃ ಷಷ್ಠಾನಿ ಇಂದ್ರಿಯಾಣಿ ಪ್ರಕೃತಿ ಸ್ಥಾನಿ ಕರ್ಷತಿ -- ಈ ದೇಹದಲ್ಲಿರುವ ಅಳಿವಿರದ ಜೀವನು ನನ್ನದೇ ಒಂದು ತುಣುಕಿನಂತೆ; (ನನ್ನ ಭಿನ್ನಾಂಶ; ನನ್ನ ಪ್ರತಿಬಿಂಬ]. ಅವನು ಶರೀರದಲ್ಲಿರುವ ಐದು ಜ್ಞಾನೇಂದ್ರಿಯಗಳನ್ನು ಆರನೆಯ ಮನಸ್ಸಿನ ಜತೆಗೆ ವಿಷಯಗಳತ್ತ ಹರಿಯಗೊಡುತ್ತಾನೆ.\n\nಜೀವನು ಭಗವಂತನ ಸನಾತನವಾದ ಅಂಕವಾಗಿದ್ದಾನೆ. ಇಲ್ಲಿ 'ಅಂಶ' ಎಂಬುದು ಎರಡು ವಿಧ: ಸ್ವರೂಪ-ಅಂಶ (ಜ್ಞಾನ ಮತ್ತು ಆನಂದದ ಸ್ವಭಾವವನ್ನು ಹಂಚಿಕೊಳ್ಳುವ ಮತ್ಸ್ಯ ಮುಂತಾದ ರೂಪಗಳು) ಮತ್ತು ಭಿನ್ನ-ಅಂಶ (ಪ್ರತಿಬಿಂಬಭೂತನಾದ ಜೀವ).\n\nಜೀವನು ಪ್ರಕೃತಿಯಲ್ಲಿರುವ ಮನಸ್ಸು ಮತ್ತು ಐದು ಇಂದ್ರಿಯಗಳನ್ನು ತನ್ನ ಕಡೆಗೆ ಸೆಳೆಯುತ್ತಾನೆ. ಭಗವಂತನೊಂದಿಗಿನ ಜೀವದ ಸಂಬಂಧವು ಶಾಶ್ವತವಾದದ್ದು.",
  "15.8": "ಶರೀರಮ್‌ ಯತ್‌ ಅವಾಪ್ನೋತಿ ಯತ್‌ ಚ ಅಪಿ ಉತ್ಕಾಮತಿ ಈಶ್ವರಃ |\nಗೃಹೀತ್ವಾ ಏತಾನಿ ಸಂಯಾತಿ ವಾಯುಃ ಗಂಧಾನ್‌ ಇವ ಆಶಯಾತ್‌ -- ವಾಸ್ತವವಾಗಿ ಜೀವ ಈ ಶರೀರವನ್ನು ಹೊಕ್ಕಾಗ ಮತ್ತು ಬಿಟ್ಟು ಹೊರಟಾಗ ಸರ್ವಶಕ್ತನಾದ ಭಗವಂತನೇ ಈ ಇಂದ್ರಿಯಗಳನ್ನು ನಿಯಂತ್ರಿಸುತ್ತಾ ಜತೆಗೆ ಬರುತ್ತಾನೆ; ಗಾಳಿ ಹೂವಿನ ಕಂಪನ್ನು ಹೊತ್ತು ಬಂದಂತೆ. [ಭಗವಂತ ಈ ಜೀವದ ಶರೀರವನ್ನು ಹೊಕ್ಕಾಗ ಮತ್ತು ಹೊರಬಂದಾಗ ಐದು ಜ್ಞಾನೇಂದ್ರಿಯಗಳನ್ನು ಆರನೆಯ ಮನಸ್ಸಿನ ಜತೆಗೆ ತನ್ನಂಕೆಯಲ್ಲಿರಿಸಿಕೊಳ್ಳುತ್ತಾನೆ. ಜೀವನಿಗೆ ವಿಷಯಾನುಭವ ನೀಡುವಾಗ ಇವುಗಳನ್ನು ಜತೆಗೊಯ್ಯುತ್ತಾನೆ.- ಗಾಳಿ ಹೂವಿಂದ ಕಂಪನ್ನು ಜತೆಗೊಯ್ಯುವಂತೆ.]\n\nಈ ಶ್ಲೋಕ ಭಗವಂತ ಮತ್ತು ಜೀವ ಎರಡನ್ನೂ ವಿವರಿಸುವ ಶ್ಲೋಕ. ಇಲ್ಲಿ ನಮಗೆ ಸ್ವಲ್ಪ ಗೊಂದಲವೆನಿಸುವ\nಮಾತನ್ನು ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ. ಈ ಮಾತನ್ನು ಬೇರೆ ಬೇರೆ ಮುಖದಲ್ಲಿ ಸ್ಪಷ್ಟವಾಗಿ ತಿಳಿದುಕೊಳ್ಳದೇ ಇದ್ದರೆ\nಎಲ್ಲವೂ ಅಸ್ಪಷ್ಟವೆನಿಸುತ್ತದೆ. ಮೇಲ್ನೋಟದಲ್ಲಿ ನೋಡಿದರೆ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಎಲ್ಲಾ ಜೀವರೂ ನನ್ನದೇ\nಅಂಶ” ಎಂದು. ಇಲ್ಲಿ ಅಂಶ ಎನ್ನುವಲ್ಲಿ ಎರಡು ಮುಖವಿದೆ. ಒಂದು ಸ್ವರೂಪಭೂತ ಅಂಶ ಮತ್ತು ಇನ್ನೊಂದು\nಭಿನ್ನಾಂಶ. ಭಗವಂತ ಜ್ಞಾನ ಸ್ವರೂಪ, ಈ ಜೀವನೂ ಕೂಡಾ ಜ್ಞಾನ ಸ್ವರೂಪ. ಭಗವಂತ ಮಹಾ ಬೆಳಕಾದರೆ\nಜೀವ ಬೆಳಕಿನ ಕಿಡಿ. ಭಗವಂತ ಬಿಂಬವಾದರೆ ಜೀವ ಪ್ರತಿಬಿಂಬ. ಇದು ಸನಾತನ- ಅನಾದಿ\nಅನಂತವಾಗಿರುವಂತಹದ್ದು. ಜೀವ ಭಗವಂತನ ಪ್ರತಿಬಿಂಬ ಅಂದರೆ ಅದು ಭಗವಂತನ ಭಿನ್ನಾಂಶ. ಈ\nಜೀವನೊಳಗೆ “ಜೀವನಾಗಿ' ಧಾರಣೆ ಮಾಡಿಕೊಂಡು ಉಸಿರಾಡಿಸುವವ ಬಿಂಬರೂಪಿ ಭಗವಂತ. ಅದು\nಭಗವಂತನ ಸ್ವರೂಪಾಂಶ. ಈ ರೀತಿ ಜೀವ ಹೊರಗಿನ ಪಂಚಭೂತವನ್ನು ಅನುಭವಿಸುವ ಐದು ಇಂದ್ರಿಯ,\nಮತ್ತು ಈ ಅನುಭವವನ್ನು ಒಳಗಿನ ಜೀವಕ್ಕೆ ಮುಟ್ಟಿಸುವ ಆರನೇ ಮನಸ್ಸಿನೊಂದಿಗೆ, ಬಿಂಬರೂಪಿ ಭಗವಂತನ\nಧಾರಣೆಯಲ್ಲಿ, _ ತಾಯಿಯ ಗರ್ಭದಲ್ಲಿ ರೂಪುಗೊಳ್ಳುತ್ತಿರುವ ಸ್ಥೂಲ ಶರೀರವನ್ನು ಪ್ರವೇಶ\nಮಾಡುತ್ತಾನೆ(ಭಗವಂತ ಪ್ರವೇಶ ಮಾಡಿಸುತ್ತಾನೆ). ಹೀಗೆ ಪ್ರವೇಶ ಮಾಡಿದ ಜೀವಕ್ಕೆ ಬಿಂಬರೂಪಿ ಭಗವಂತ\nಸರ್ವೆಂದ್ರಿಯದಲ್ಲಿದ್ದು, ಇಂದ್ರಿಯಾಭಿಮಾನಿ ದೇವತೆಗಳ ಮುಖೇನ ಅನುಭವ ಕೊಡುತ್ತಾನೆ. ಜೀವ ಭಗವಂತನ\nಅನುಗ್ರಹದಿಂದ ವಿಷಯಗಳನ್ನು ಅನುಭವಿಸಲು ಆರಂಭಿಸುತ್ತಾನೆ.\n\nಒಬ್ಬ ಜೀವನಿಗೆ ಒಟ್ಟು ಮೂರು ಶರೀರಗಳಿರುತ್ತವೆ. ಒಂದು ಕಾಣುವ ಸ್ಥೂಲ ಶರೀರ, ಅದರೊಳಗೆ ಸೂಕ್ಷ್ಮ\nಶರೀರ(ಅನಿರುದ್ಧ ಶರೀರ) ಮತ್ತು ಅದರೊಳಗೆ ಲಿಂಗ ಶರೀರ. ಈ ಸ್ಥೂಲ ಶರೀರವನ್ನು ಪ್ರವೇಶಿಸುವ\nಸೂಕ್ಷ್ಮಶರೀರಿ ಜೀವಕ್ಕೆ ಎಲ್ಲಾ ಇಂದ್ರಿಯಗಳೂ ಇರುತ್ತವೆ. ಆದ್ದರಿಂದ ಈ ಜೀವ ತನ್ನ ಪೂರ್ವಜನ್ಮದ ನೆನಪನ್ನು\nಅಂತರಂಗದಲ್ಲಿಟ್ಟುಕೊಂಡು ಗರ್ಭವನ್ನು ಪ್ರವೇಶಿಸುತ್ತಾನೆ. ಪೂರ್ವ ಜನ್ಮದ ಅಧ್ಯಾತ್ಮ ಸಾಧನೆ ಈ ಸೂಕ್ಷ್ಮ\nಜೀವದ ಮನಸ್ಸಿ ನಲ್ಲಿ ಪೂರ್ಣವಾಗಿ ಉಳಿದಿರುತ್ತದೆ. ಇದಕ್ಕಾಗಿ \"ಅಧ್ಯಾತ್ಮ ಸಾಧನೆ ಎಂದೂ ವ್ಯರ್ಥವಾಗುವುದಿಲ್ಲ,\nಅದು ಸದಾ ನಮ್ಮೊಂದಿಗೆ ಸಾವಿನಲ್ಲೂ ಜೊತೆಯಾಗಿ ಬರುತ್ತದೆ' ಎಂದು ಹೇಳುವುದು. ಏಕೆಂದರೆ ಸಾವು ಕೇವಲ\nಸ್ಥೂಲ ಶರೀರಕ್ಕೇ ಹೊರತು ಸೂಕ್ಷ್ಮಶರೀರಕ್ಕಲ್ಲ. ಸಂಮೋಹನ ನಿದ್ರೆಯಲ್ಲಿ(hypnosis) ಜೀವದ ಪೂರ್ವಜನ್ಮದ\nವಿಷಯವನ್ನು ತಿಳಿಯಲು ಸಾಧ್ಯವಾಗುವುದು ಈ ಕಾರಣದಿಂದ. ನಮಗೆ ಕೆಲವೊಮ್ಮೆ ಒಬ್ಬರನ್ನು ನೋಡಿದಾಗ\nಹಿಂದೆ ತುಂಬಾ ಪರಿಚಿತರಾಗಿ ನಮ್ಮೊಂದಿಗಿದ್ದವರಂತೆ ಕಂಡರೆ-ಅದಕ್ಕೆ ಪೂರ್ವ ಜನ್ಮದ ನೆನಪೂ ಒಂದು\nಕಾರಣವಾಗಿರಬಹುದು. ಈ ನೆನಪು ಒಳಗಿರುವ ಸೂಕ್ಷ ಶರೀರದಲ್ಲಿ ಮಾತ್ರ ಜಾಗೃತವಾಗಿರುತ್ತದೆ-ಆದರೆ ಸ್ಥೂಲ\nಇಂದ್ರಿಯದಲ್ಲಿ ಇದು ಜಾಗೃತವಾಗಿರುವುದಿಲ್ಲ. ಹೀಗೆ ಜೀವ ಸ್ಥೂಲ ಶರೀರವನ್ನು ಪ್ರವೇಶ ಮಾಡುವಾಗ\nಇಂದ್ರಿಯಗಳನ್ನು ಕರ್ಷಣೆ ಮಾಡಿಕೊಂಡು ಬರುತ್ತಾನೆ ಮತ್ತು ಹೋಗುವಾಗ ಕರ್ಷಣೆ ಮಾಡಿಕೊಂಡು\nಹೋಗುತ್ತಾನೆ. ಈ ಕ್ರಿಯೆಯಲ್ಲಿ ಜೀವ ಸ್ವತಂತ್ರನಲ್ಲ. ಇದನ್ನು ಮಾಡಿಸುವವ “ಈಶ್ವರ'. ಇಲ್ಲಿ ಈಶ್ವರ ಎಂದರೆ\n\nಸರ್ವ ಸಮರ್ಥ ಭಗವಂತ ಎಂದರ್ಥ. ಶಂಕರಾಚಾರ್ಯರು ತಮ್ಮ ಭಾಷ್ಯದಲ್ಲಿ “ಈಶ್ವರಃ ಈಶನಶೀಲೋ\nನಾರಾಯಣಃ” ಎಂದಿದ್ದಾರೆ. ಇಲ್ಲಿ \"ಈಶನಶೀಲಃ' ಎಂದರೆ ಸರ್ವಸಮರ್ಥ ಎಂದರ್ಥ.\n\nಈ ಶ್ಲೋಕದಲ್ಲಿ ಶಬ್ದಗಳ ಚಮತ್ಕಾರವಿದೆ. “ಅವಾಪ್ನೋತಿ' ಎನ್ನುವಲ್ಲಿ \"ಅವ' ಅನ್ನುವುದು ಉಪಸರ್ಗ. ಹದಿನೈದು\nಬೇಲಿಗಳೊಂದಿಗೆ ಜೀವ ದೇಹವನ್ನು ಪ್ರವೇಶಿಸುವುದು ಜೀವದ ಬಂಧನ. ಇದು ಒಂದು ರೀತಿಯ 'ಅಧಃಪಾತ'.\nಆದರೆ ಇದು ಊರ್ಧ್ವಗಮನಕ್ಕೆ ಪೂರ್ವ ಜೀವದ ಅಧಃಪಾತ. ಏಕೆಂದರೆ ಜೀವ ಮೋಕ್ಷ ಸೇರಲು ಈ ಸಾಧನಾ\nಶರೀರ ಬೇಕೇಬೇಕು. ಇದೇ ರೀತಿ ಜೀವ ದೇಹವನ್ನು ಬಿಟ್ಟು ಹೊರ ಹೋಗುವುದನ್ನು \"ಉತ್ಕಾಮತಿ' ಎಂದಿದ್ದಾರೆ.\nಸಾವು ಎಂದರೆ ಜೀವನನ್ನು ಭಗವಂತ ಸ್ಥೂಲ ಶರೀರದಿಂದ ಆಚೆ ಕರೆದುಕೊಂಡು ಹೋಗುವುದು. ಇದು\nಅಮಂಗಳವಲ್ಲ. ಅದಕ್ಕಾಗಿ ಇಲ್ಲಿ \"ಉತ್‌' ಎನ್ನು ವ ಉಪಸರ್ಗವನ್ನು ಬಳಸಲಾಗಿದೆ. ಇನ್ನು ಭಗವಂತ ಜೀವನನ್ನು\nಕರೆತರುವುದನ್ನು ಇಲ್ಲಿ 'ಸಂಯಾತಿ' ಎಂದಿದ್ದಾರೆ. ಸಂ-ಎಂದರೆ ಸ್ವಯಂ, ಸ್ವೇಚ್ಛಾಯ, ಸ್ವಾತಂತ್ರೇಣ. ಎಲ್ಲವೂ\nಭಗವಂತನ ಅಧೀನ, ಜೀವ ಸ್ವತಂತ್ರ ಅಲ್ಲ, ಕೇವಲ ಭಗವಂತ ಸ್ವತಂತ್ರ ಅನ್ನುವುದನ್ನು ಇದು ಸೂಚಿಸುತ್ತದೆ.\nಜೀವನಿಗೆ ಹುಟ್ಟು ವುದಕ್ಕಾಗಲೀ, ಸಾಯುವುದಕ್ಕಾಗಲೀ ಸ್ವಾತಂತ್ರ್ಯವಿಲ್ಲ. ಎಲ್ಲವೂ ಭಗವಂತನ\nನಿಯಮನದಂತೇ ನಡೆಯುತ್ತದೆ.\n\nಹೇಗೆ ಜೀವ ತನ್ನ ಇಂದ್ರಿಯಗಳೊಂದಿಗೆ ಭಗವಂತನ ಜೊತೆಗೆ ಒಳ ಬರುತ್ತದೆ ಮತ್ತು ಹೊರ ಹೋಗುತ್ತದೆ\nಎನ್ನುವುದನ್ನು ಹೂವಿನ ಸುಗಂಧದ ದೃಷ್ಟಾಂತದೊಂದಿಗೆ ಕೃಷ್ಣ ವಿವರಿಸಿದ್ದಾನೆ. ಅರಳಿ ನಿಂತಿರುವ ಹೂವಿನ\nಸುಗಂಧ ಹೇಗೆ ನಮ್ಮ ಮೂಗನ್ನು ಬಂದು ಪ್ರವೇಶಿಸುತ್ತದೆಯೋ ಹಾಗೇ ಈ ಜೀವದ ಗತಿ. ಅದು ಕಾಣುವುದಿಲ್ಲ.\nಹೂವಿನ ಸುಗಂಧದ ಸೂಕ್ಷ್ಮಾಣುಗಳು ನಮ್ಮ ಮೂಗನ್ನು ಪ್ರವೇಶಿಸುವುದು ನಮಗೆ ತಿಳಿಯುವುದು ಕೇವಲ\nಸುವಾಸನೆಯಿಂದಾಗಿ, ಹೊರತು ಭೌತಿಕವಾಗಿ ಅಲ್ಲ. ಜೀವದ ಈ ಎಲ್ಲಾ ಗತಿ ಕೂಡಾ ಇದೇ ರೀತಿ. ಅದು\nಕಾಣುವುದಿಲ್ಲ. ಇದನ್ನೇ ಇನ್ನೂ ಸ್ಪಷ್ಟವಾಗಿ ಕೃಷ್ಣ ಮುಂದಿನ ಮೂರು ಶ್ಲೋಕದಲ್ಲಿ ವಿವರಿಸುತ್ತಾನೆ.",
  "15.9": "ಶ್ರೋತ್ರಮ್‌ ಚಕ್ಷುಃ ಸ್ಪರ್ಶನಮ್‌ ಚ ರಸನಮ್‌ ಘ್ರಾಣಮ್‌ ಏವ ಚ |\nಅಧಿಷ್ಠಾಯ ಮನಃ ಚ ಅಯಮ್‌ ವಿಷಯಾನ್‌ ಉಪಸೇವತೇ-ಕಿವಿ, ಕಣ್ಣು, ತೊಗಲು, ನಾಲಿಗೆ, ಮೂಗು ಮತ್ತು\nಮನಸ್ಸಿನಲ್ಲಿ ನೆಲೆನಿಂತು 'ಇವನು' ವಿಷಯಗಳನ್ನು ಸವಿಯುತ್ತಾನೆ.\n\nಭಗವಂತ ನಮ್ಮ ಪ್ರತಿಯೊಂದು ಇಂದ್ರಿಯದಲ್ಲಿ ನಿಯಾಮಕನಾಗಿ ಆಯಾ ರೂಪದಲ್ಲಿ ನಿಂತು, ವಿಷಯಗಳನ್ನು\nದುಃಖದ ಲೇಪವಿಲ್ಲದೆ. ಗ್ರಹಿಸುತ್ತಾನೆ ಮತ್ತು ನಮಗೆ ವಿಷಯದ ಅನುಭವವನ್ನು ಕೊಡುತ್ತಾನೆ. ಈ ಶ್ಲೋಕ\nಭಗವಂತನನ್ನು ಹೇಳುವುದರಿಂದ ಇಲ್ಲಿ \"ಉಪ-ಸೇವತೆ' ಮತ್ತು “ಅಧಿಷ್ಠಾಯ' ಎನ್ನುವ ಎರಡು ವಿಶೇಷ\nಪದಗಳನ್ನು ಬಳಸಿದ್ದಾರೆ. ಉಪ ಅಂದರೆ -ಉಪರಿ-ಎತ್ತರ. ನಾವು ಸುಖ-ದುಃಖದಲ್ಲಿ ಮುಳುಗಿ ವಿಷಯ\nಭೋಗಿಸಿದರೆ, ಭಗವಂತ ಎಲ್ಲವನ್ನೂ ಮೀರಿನಿಂತು ದುಃಖದ ಲೇಪವಿಲ್ಲದೆ ಎಲ್ಲವನ್ನೂ ಅನುಭವಿಸುತ್ತಾನೆ.\n\nಭಗವಂತ ಆಯಾ ಇಂದ್ರಿಯದಲ್ಲಿ ವಿಶೇಷ ರೂಪದಲ್ಲಿ ಸನ್ನಿಹಿತನಾಗಿ ನಿಯಮಿಸುವುದರಿಂದ ಇಲ್ಲಿ \"ಅಧಿಷ್ಠಾಯ'\nಎನ್ನುವ ಪದವನ್ನು ಬಳಸಲಾಗಿದೆ. ಏವ ಮತ್ತು ಚ ಇವೆರಡನ್ನು ಈ ಶ್ಲೋಕದಲ್ಲಿ ಒಟ್ಟಾಗಿ ಬಳಸಲಾಗಿದೆ. ಇದು\nಭಗವಂತನ ವಿಶೇಷ ಗುಣವನ್ನು ಬಿಂಬಿಸುತ್ತದೆ. ಅ+ಊ+ವ+ಚ=ಏವಚ(set of abbreviations-ಸಂಕ್ಷೇಪ-ಪದ)-\nಅಂದರೆ ಯಾವುದೇ ದೋಷವಿಲ್ಲದ, ಸರ್ವಗುಣಗಳಿಂದ ಸಮುಚ್ಚಿ ತವಾದ ಜ್ಞಾನಾನಂದಮಯ ಭಗವಂತ.\n",
  "15.10": "ಉತ್‌ ಕ್ರಾಮಂತಮ್‌ ಸ್ಥಿತಮ್‌ ವಾ ಅಪಿ ಭುಂಜಾನಮ್‌ ವಾ ಗುಣ ಅನ್ವಿತಮ್‌ |\n\nವಿಮೂಢಾಃ ನ ಅನುಪಶ್ಯಂತಿ ಪಶ್ಯಂತಿ ಜ್ಞಾನ ಚಕ್ಷುಷಃ -ದೇಹ ತೊರೆದು ತೆರಳುವ, ದೇಹದಲ್ಲಿರುವ, ಅಥವಾ\nಒಳಿತಿನ ಸಾರವನ್ನು ಸವಿಯುವ ಇವನನ್ನು ತಿಳಿಗೇಡಿಗಳು ತಿಳಿಯಲಾರರು. ತಿಳಿಗಣ್ಣು ತೆರೆದವರು\nತಿಳಿಯಬಲ್ಲರು.\n\nಈ ಶ್ಲೋಕದಲ್ಲಿ ಬಳಸಿರುವ 'ಗುಹಾನ್ವಿತಮ್‌' ಎನ್ನುವ ಪದ ಸ್ಪಷ್ಟವಾಗಿ ನಮಗೆ ತಿಳಿಸುತ್ತದೆ-ಇದು\nಭಗವಂತನನ್ನು ಹೇಳುವ ಶ್ಲೋಕ ಎಂದು. ಜೀವನನ್ನು ದೇಹಕ್ಕೆ ತರುವ, ಎಚ್ಚರ ಕನಸು ನಿದ್ದೆ ಎನ್ನುವ ಮೂರು\nಅವಸ್ಥೆಗಳಲ್ಲಿ ಜೀವನಿಗೆ ವಿಷಯ ಭೋಗವನ್ನು ಕೊಡುವ ಭಗವಂತ-ತಾನು ಸದಾ ಶುಭ ಭೋಗವನ್ನುಣ್ಣುವವ.\nದೇಹದಿಂದ ಹೊರ ಹೋಗುವಾಗ, ದೇಹದಲ್ಲಿರುವಾಗ-ಎಲ್ಲವನ್ನು ಮಾಡಿಸುವವ ಆ ಭಗವಂತ. ಆತ ನಮ್ಮೊಳಗೇ\nಇದ್ದರೂ ಕೂಡಾ ವಿಮೂಢರಿಗೆ ಇದು ತಿಳಿಯುವುದಿಲ್ಲ. ಜ್ಞಾನದ ಕಣ್ಣುತೆರೆದವರು ಮಾತ್ರ ಇದನ್ನು ತಿಳಿಯಬಲ್ಲರು.\nಇಲ್ಲಿ ಕೃಷ್ಣ 'ವಿಮೂಢ' ಮತ್ತು “ಜ್ಞಾನಚಕ್ಷುಷಃ' ಎನ್ನುವ ಎರಡು ವಿಶೇಷ ಪದಗಳನ್ನು ಬಳಸಿದ್ದಾನೆ. ಮೂಢರು'\nಎಂದರೆ ಸತ್ಯವನ್ನು ತಪ್ಪಾಗಿ ತಿಳಿದವರು. ಇವರು ಯಥಾರ್ಥಜ್ಞಾನ ಮರೆಯಾಗಿ ವಿಪರೀತಜ್ಞಾನದಲ್ಲೇ\nಬದುಕುತ್ತಿರುತ್ತಾರೆ. “ವಿ-ಮೂಢ' ಎಂದರೆ ಎಂದೂ ತಮ್ಮ ತಪ್ಪನ್ನು ತಿಳಿಯದೇ, ತಪ್ಪನ್ನೇ ಸರಿಯೆಂದು ಸದಾ\nವಿಪರೀತ ಜ್ಞಾನದಲ್ಲೇ ಬದುಕುವವರು. ಇವರಿಗೆ ಭಗವಂತನನ್ನು ಎಂದೆಂದಿಗೂ ತಿಳಿಯಲು ಸಾಧ್ಯವಿಲ್ಲ.\nಭಗವಂತನನ್ನು ಕಾಣುವ ಕ್ಷಮತೆ ಉಳ್ಳವರು ಜ್ಞಾನಚಕ್ಷುಷರು. ಅಂದರೆ ಶಾಸ್ತ್ರವನ್ನು ಓದಿ ಅದರಿಂದ ಅರಿವಿನ\nಒಳಗಣ್ಣು ತೆರೆದವರು. ಇವರು ಭಗವಂತನನ್ನು ತಿಳಿಯಬಲ್ಲರು ಮತ್ತು ತಮ್ಮ ಸ್ವರೂಪಭೂತವಾದ ಕಣ್ಣಿನಿಂದ\nಭಗವಂತನನ್ನು ಕಾಣಬಲ್ಲರು.\n",
  "15.11": "ಯತಂತಃ ಯೋಗಿನಃ ಚ ಎನಮ್‌ ಪಶ್ಯಂತಿ ಆತ್ಮನಿ ಅವಸ್ಥಿತಮ್‌ |\nಯತಂತಃ ಅಪಿ ಅಕೃತ ಆತ್ಮಾನಃ ನ ಏನಮ್‌ ಪಶ್ಯಂತಿ ಅಚೇತಸಃ -ಪ್ರಯತ್ನ ಶೀಲರಾದ ಸಾಧಕರು-\n\nತಮ್ಮೊಳಗಿರುವ \"ಇವನನ್ನು ' ಕಾಣುತ್ತಾರೆ. ತಿಳಿಯಾದ ತಿಳಿವಿರದ ತಿಳಿಗೇಡಿಗಳು ಪ್ರಯತ್ನಿ ಸಿಯೂ ಇವನನ್ನು\nಕಾಣಲಾರರು.\n\nಭಗವಂತನನ್ನು ಕಾಣಬೇಕಾದರೆ ಕೇವಲ ಶಾಸ್ತ್ರಾಭ್ಯಾಸ ಮಾಡಿದರೆ ಸಾಲದು. ಜ್ಞಾನ ಪಡೆದು ಜ್ಞಾನದಿಂದ\nನಿರಂತರ ಸಾಧನೆ ಅಗತ್ಯ. ಧ್ಯಾನ ಯೋಗದಿಂದ ನಿರಂತರ ಭಗವಂತನನ್ನು ಕಾಣುವ ಪ್ರಯತ್ನ ಮಾಡಿದಾಗ-\nಆತ್ಮಸಾಕ್ಷಾತ್ಕಾರವಾಗುತ್ತದೆ[ಧ್ಯಾನದ ಕುರಿತು ಅಧ್ಯಾಯ ಆರರಲ್ಲಿ. ಈಗಾಗಲೇ ನಾವು ಸಾಕಷ್ಟು\nಚರ್ಚಿಸಿದ್ದೇವೆ], ಭಗವಂತನನ್ನು ಕಾಣಲು ನಮ್ಮ ಪ್ರಯತ್ನದೊಂದಿಗೆ ಆತನ ಅನುಗ್ರಹವೂ ಬೇಕು. ಇಲ್ಲದಿದ್ದರೆ\nಯಾವ ಮಹಾಪ್ರಯತ್ನದಿಂದಲೂ ಭಗವಂತನನ್ನು ಕಾಣಲು ಸಾಧ್ಯವಿಲ್ಲ. ಉದಾಹರಣೆಗೆ ನಾವು ಹೊಲವನ್ನು\nಚೆನ್ನಾಗಿ ಉತ್ತು, ಹದಗೊಳಿಸಿ, ಗೊಬ್ಬರ ಹಾಕಿ ಉತ್ತಮ ದರ್ಜೆಯ ಬೀಜ ಬಿತ್ತಬಹುದು, ಆದರೆ ಮಳೆ ಸರಿಯಾಗಿ\nಬಾರದಿದ್ದರೆ? ಅತಿ ಮಳೆ ಬಂದು ಕೊಚ್ಚಿಕೊಂಡು ಹೋದರೆ? ಇದೆಲ್ಲವೂ ದೈವಾನುಗ್ರಹ. ಅದಕ್ಕಾಗಿ ನಿರಂತರ\nಪ್ರಯತ್ನದೊಂದಿಗೆ ಭಗವಂತನಲ್ಲಿ ಶರಣಾಗತಿ ಬಹಳ ಮುಖ್ಯ. “ನನ್ನ ಮನಸ್ಸನ್ನು ಸ್ವಚ್ಛಮಾಡು, ಸ್ವಚ್ಛವಾದ\nಮನಸ್ಸಿನಲ್ಲಿ ನೀನು ಬಂದು ನೆಲೆಸು” ಎಂದು ಆ ಭಗವಂತನನ್ನು ಪ್ರಾರ್ಥಿಸಬೇಕು. ಶುದ್ಧವಾದ ಸಾತ್ವಿಕ\nಮನಸ್ಸಿಗೆ 'ವಸುದೇವ' ಎನ್ನುತ್ತಾರೆ. ಆ ವಸುದೇವನಿಗೆ ಕಾಣಿಸಿಕೊಳ್ಳುವ ಭಗವಂತ ವಾಸುದೇವ. ಸಮಸ್ತಶಾಸ್ತ್ರ\nಓದಿ ಅಶುದ್ಧಮನಸ್ಸಿನವನಾಗಿದ್ದರೆ (ಅಕೃತಾತ್ಮಕ=ಅಶುದ್ಧ ಬುದ್ಧಯಃ)- ಎಷ್ಟೇ ಪ್ರಯತ್ನ ಮಾಡಿದರೂ ಭಗವಂತ\nಒಲಿಯಲಾರ. ಇದನ್ನೇ 'ಮಡಿ' ಎನ್ನುವುದು. ಮಾನಸಿಕವಾಗಿ ಮಡಿಯಾಗಿ ನಾವು ಪ್ರಯತ್ನ ಮಾಡಬೇಕು.\n“ನಿರಂತರ ಜ್ಞಾನಪೂರ್ವಕ ಪ್ರಯತ್ನದಿಂದ ನಿನ್ನ ಅತ್ಯಂತ ಸಮೀಪವಿರುವ, ನಿನ್ನಂತರಂಗದೊಳಗೆ ನಿನ್ನ\nಜೀವಸ್ವರೂಪದೊಳಗಿರುವ ಭಗವಂತನನ್ನು ಕಾಣು” ಎನ್ನುತ್ತಾನೆ. ಕೃಷ್ಣ. ಹಿಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ\nಅಯಮ್‌ ಅಸೌ(ಎದುರಿಗಿರುವ) ಎಂದ ಕೃಷ್ಣ ಇಲ್ಲಿ\"ಏನಮ್\"(ನಿನ್ನ ಅತ್ಯಂತ ಸಮೀಪವಿರುವ) ಎಂದ. ನಾವು\nಭಗವಂತನನ್ನು ಎಲ್ಲೋ ಹುಡುಕುವುದು ಬೇಡ. ಆತ ನಮ್ಮ ಜೀವ ಸ್ವರೂಪದೊಳಗೇ ಬಿಂಬ ರೂಪನಾಗಿ\nನೆಲೆಸಿದ್ದಾನೆ. ಆತನ ನೆಲೆಯಾದ ನಮ್ಮ ಜೀವಸ್ವರೂಪವನ್ನು ತಿಳಿದಾಗ ಆತ ನಮಗೆ ಕಾಣಿಸುತ್ತಾನೆ.\n",
  "15.12": "ಯತ್‌ ಆದಿತ್ಯಗತಮ್‌ ತೇಜಃ ಜಗತ್‌ ಭಾಸಯತೇ ಅಖಿಲಮ್‌ |\nಯತ್‌ ಚಂದ್ರಮಸಿ ಯತ್‌ ಚ ಅಗ್ನೌ ತತ್‌ ತೇಜಃ ವಿದ್ಧಿ ಮಾಮಕಮ್‌ -ಸೂರ್ಯನಲ್ಲಿದ್ದು ವಿಶ್ವವನ್ನೆ ಲ್ಲಾ ಬೆಳಗುವ\nಬೆಳಕು, ಚಂದ್ರನಲ್ಲಿ, ಬೆಂಕಿಯಲ್ಲಿ ಕೂಡಾ, ಅದು ನನ್ನ ದೇ ಬೆಳಕೆಂದು ತಿಳಿ.\n\nಹಿಂದೆ-ಸೂರ್ಯನಾಗಲೀ, ಚಂದ್ರನಾಗಲೀ, ಅಗ್ನಿಯಾಗಲೀ ನನ್ನನ್ನು ಬೆಳಗಿಸುವುದಿಲ್ಲ ಎಂದಿದ್ದ ಕೃಷ್ಣ, ಇಲ್ಲಿ\nಸೂರ್ಯ ಬೆಳಗುವುದು, ಚಂದ್ರ ಬೆಳಗುವುದು, ಅಗ್ನಿ ಬೆಳಗುವುದು -ಎಲ್ಲವೂ ನನ್ನಿಂದ ಎನ್ನುತ್ತಾನೆ. ಎಲ್ಲಾ ಬೆಳಕಿನ\nಮೂಲ ಬೆಳಕು ಭಗವಂತ. ಬೆಳಕಿನ ಮೂಲಗಳೆಂದರೆ ಸೂರ್ಯ, ಚಂದ್ರ, ನಕ್ಷತ್ರ, ಮಿಂಚು, ವಿದ್ಯುತ್‌ ಹಾಗೂ\n\nಅಗ್ನಿ. ಈ ಎಲ್ಲಾ ಬೆಳಕಿನ ಪುಂಜಗಳಿಗೆ ಬೆಳಕನ್ನು ಕೊಡುವನು ಆ ಭಗವಂತ. ಅಂದರೆ \"ಸೂರ್ಯನಿಂದ ಹಿಡಿದು,\nಚಂದ್ರ ತಾರೆಗಳಾಗಲೀ, ಆಕಾಶದಲ್ಲಿ ಬೆಳಗುವ ಮಿಂಚಿರಲೀ, ಅಥವಾ ಉರಿಯುವ ಅಗ್ನಿ ಯಾಗಲೀ, ಈ ಎಲ್ಲಾ\nಬೆಳಕಿನ ಪುಂಜಗಳು ಬೆಳಗುವುದು ಭಗವಂತನೆಂಬ ಮೂಲ ಬೆಳಕಿನಿಂದ. ಯಾವ ಬೆಳಕು ನಮ್ಮ\nಸ್ವರೂಪದೊಳಗೆ. ಅಣೋರಣೀಯವಾಗಿ ನಿಂತು. ನಮ್ಮನ್ನು ನಡೆಸುತ್ತಿದೆಯೋ, ಅದೇ ಬೆಳಕು\nಮಹತೋಮಹಿಯಾಗಿ ಇಡೀ ಬ್ರಹ್ಮಾಂಡವನ್ನು ಬೆಳಗಿಸುತ್ತಿದೆ. ಒಟ್ಟಿನಲ್ಲಿ ಎಲ್ಲಾ ಬೆಳಕುಗಳ ಮೂಲ ತೇಜಸ್ಸು ಆ\nಭಗವಂತ. ಉಪನಿಷತ್ಕಾರರು ಇಂತಹ ಮಹಾ ಬೆಳಕಿನ ಬಗ್ಗೆ ವಿವರಿಸುತ್ತಾ ಹೇಳುತ್ತಾರೆ: “..ಯದೇತದ್‌\nವಿದ್ಯುತೋ ವ್ಯದ್ಯುತದಾ ಇತಿ.” ಎಂದು (ಕೇನ-೪.೪). ಅವರು ಇಲ್ಲಿ ಈ ಬೆಳಕನ್ನು “ಆ-ಇತಿ' ಎನ್ನುತ್ತಾರೆ.\nಅಂದರೆ ಇದೊಂದು 'ವಿಸ್ಮಯ' ಎಂದರ್ಥ. ತಿಳಿಯುವ ತನಕ ಆಶ್ಚರ್ಯ, ತಿಳಿದ ಮೇಲೆ ಆನಂದ.\n\nಉಪಾಸನೆಯ ದೃಷ್ಟಿಯಲ್ಲಿ ಈ ಶ್ಲೋಕವನ್ನು ನೋಡಿದರೆ: ಸೂರ್ಯನಲ್ಲಿರುವ ತೇಜಸ್ಸು-ನಾರಾಯಣನ\nತೇಜಸ್ಸು, ಚಂದ್ರನಲ್ಲಿರುವ ತೇಜಸ್ಸು-ಧನ್ವಂತರಿಯ ತೇಜಸ್ಸು, ಅಗ್ನಿಯಲ್ಲಿರುವ ತೇಜಸ್ಸು-ಪರಶುರಾಮನ\nತೇಜಸ್ಸು. ಹೀಗೆ ಪ್ರತಿಯೊಂದು ಬೆಳಕಿನ ಮೂಲ ಬೆಳಕು ಭಗವಂತ ಎಂದು ನಾವು ಈ ಶ್ಲೋಕದಿಂದ ಉಪಾಸನೆ\nಮಾಡಬಹುದು.\n",
  "15.13": "ಗಾಮ್‌ ಆವಿಶ್ಯ ಚ ಭೂತಾನಿ ಧಾರಯಾಮಿ ಅಹಮ್‌ ಓಜಸಾ ।\n\nಪುಷ್ಣಾಮಿ ಚ ಓಷಧೀಃ ಸರ್ವಾಃ ಸೋಮಃ ಭೂತ್ವಾ ರಸಾತ್ಮಕಃ -ಭೂಮಿಯೊಳಹೊಕ್ಕು ಜೀವಿಗಳನ್ನು ನಾನೇ\nನನ್ನಳವಿನಿಂದ ಹೊತ್ತಿದ್ದೇನೆ. ಅಮೃತ ರಸಮಯನಾದ ಚಂದ್ರನಾಗಿ [ಸೌಮ್ಯರೂಪನಾದ್ದರಿಂದ 'ಸೋಮ'\nನಾಮಕನಾಗಿ ಚಂದ್ರನೊಳಗಿದ್ದು] ಎಲ್ಲಾ ಸಸ್ಯಗಳನ್ನು ಬೆಳೆಸುತ್ತೇನೆ.\n\nಇಲ್ಲಿ ಗಾಮ್‌ ಅಂದರೆ 'ಪ್ರಥಿವಿ. ಈ ಭೂಮಿ ಆಕಾಶದಲ್ಲಿ ನಿರಾಲಂಭವಾಗಿ ನಿಲ್ಲುವಂತೆ ಸಂಕರ್ಷಣಶಕ್ತಿ\n(ಶೇಷಶಕ್ತಿ-ಆಕರ್ಷಣಶಕ್ತಿ- Gravitational force) ರೂಪದಲ್ಲಿ ಭೂಮಿಯನ್ನು ಹೊತ್ತವನು ಭಗವಂತ. ಇದು\nಭಗವಂತನ ವರಾಹ ಅವತಾರವನ್ನು ವಿವರಿಸುತ್ತದೆ. ಕೆಳಕ್ಕೆ ಕುಸಿದು ನಾಶವಾಗಲಿದ್ದ ಭೂಮಿಯನ್ನು ಭಗವಂತ\nವರಾಹ ರೂಪದಲ್ಲಿ ಎತ್ತಿ ಹಿಡಿದ-ಎನ್ನುವುದು ಕಥೆ. ಇಲ್ಲಿ ಭೂಮಿ ಕೆಳಕ್ಕೆ ಕುಸಿಯುವುದು ಅಂದರೆ ಅದು ತನ್ನ\nಕಕ್ಷೆಯಿಂದ ಕಳಚುವುದು. ಭೂಮಿ ಕಕ್ಷೆಯನ್ನು ಬಿಟ್ಟರೆ ಅದು ಕ್ಷಣಾರ್ಧದಲ್ಲಿ ನಾಶವಾಗುತ್ತದೆ. ತಾಮಸ ಲೋಕದ\nದೈತ್ಯ ಹಿರಣ್ಯಾಕ್ಷ ಭೂಮಿಯನ್ನು ಕಕ್ಷೆಯಿಂದ ತಪ್ಪಿಸಿದವ. “ನನಗೆ ನಿಲ್ಲಲು ಒಂದು ಜಾಗ ಮತ್ತು ಒಂದು\nಕೋಲನ್ನು ಕೊಟ್ಟರೆ ನಾನು ಭೂಮಿಯನ್ನು ಕಕ್ಷೆಯಿಂದ ಕಳಚಬಲ್ಲೆ” ಎಂದು ನ್ಯೂಟನ್‌ ಹೇಳಿರುವುದನ್ನು ನಾವು\nಇಲ್ಲಿ ನೆನಪಿಸಿಕೊಳ್ಳಬಹುದು. ಈ ರೀತಿ ತಾಮಸ ಲೋಕದ ದೈತ್ಯ ಭೂಮಿಯನ್ನು ಕಕ್ಷೆಯಿಂದ ತಪ್ಪಿಸಿದಾಗ,\nಭಗವಂತ ಅದನ್ನು ಮರಳಿ ಕಕ್ಷೆಯಲ್ಲಿಟ್ಟು ರಕ್ಷಿಸಿದ. ವೇದಕಾಲದ ಖುಷಿಗಳಿಗೆ 'ಭೂಮಿಯನ್ನು ಧಾರಣೆ ಮಾಡಿದ\nಭಗವಂತ ವರಾಹ ರೂಪನಾಗಿ ಕಂಡ'. ಈ ಕಾರಣದಿಂದ ಭೂಮಿಯನ್ನು ಧಾರಣೆ ಮಾಡಿರುವ ಭಗವಂತನ\n\nರೂಪವನ್ನು ವರಾಹ ರೂಪದಲ್ಲಿ ಕಾಣುತ್ತೇವೆ. ವರಶ್ರೇಷ್ಠ. ಗಾಯತ್ರಿಯಲ್ಲಿ ವರೇಣ್ಯಂ' ಎನ್ನುವಲ್ಲಿ ಭೂಮಿಯನ್ನು\nಧಾರಣೆ. ಮಾಡಿರುವ ಭಗವಂತನ ವರಾಹ ರೂಪದ ಚಿಂತನೆ ಇದೆ. ರಷ್ಯನ್‌ ವಿಜ್ಞಾನಿ\nವಿಲಿಕೋವಸ್ಕಿ(Velikovsky) ತನ್ನ \"Worlds in Collision\" ಎನ್ನುವ ಪುಸ್ತಕದಲ್ಲಿ ಹೇಳುತ್ತಾನೆ. :\n“ವೈಜ್ಞಾನಿಕವಾಗಿ ಎರಡು ಬಾರಿ ಭೂಮಿ ತನ್ನ ಕಕ್ಷೆಯಿಂದ ತಪ್ಪಿದ್ದು ನಿಜ, ಆದರೆ ನಮಗೆ ಇದು ಏಕೆ ಎನ್ನುವುದು\nತಿಳಿದಿಲ್ಲ” ಎಂದು. ಆತ ಅಲ್ಲಿ ಭಾಗವತವನ್ನು ಉಲ್ಲೇಖಿಸಿ ಹೇಳುತ್ತಾನೆ: “ಭಾರತದ ಖುಷಿಗಳು ಈ ವಿಚಾರವನ್ನು\nತಿಳಿದಿದ್ದರು, ಒಂದು ದುಷ್ಟ ಶಕ್ತಿ ಭೂಮಿಯನ್ನು ಕಕ್ಷೆಯಿಂದ ಕಳಚಿತು, ಹಾಗೂ ಇನ್ನೊಂದು ದೈವೀ ಶಕ್ತಿ ಅದನ್ನು\nಮರಳಿ ಕಕ್ಷೆಯಲ್ಲಿಟ್ಟಿತು” ಎಂದು. ಇದನ್ನೇ ಈ ಶ್ಲೋಕದಲ್ಲಿ ಕೃಷ್ಣ “ಗ್ರಾಮ್‌ ಧಾರಯಾಮಿ” ಎಂದಿದ್ದಾನೆ.\nಭೂಮಿಯನ್ನು ಧಾರಣೆ ಮಾಡಿರುವ ಭಗವಂತ ಭೂಮಿಯೊಳಗಿದ್ದು, ಪ್ರತಿಯೊಂದು ಜೀವಜಾತದೊಳಗಿದ್ದು\nನಮ್ಮನ್ನು ರಕ್ಷಿಸುತ್ತಿದ್ದಾನೆ. ಉಪನಿಷತ್ತಿನಲ್ಲಿ ಹೇಳುವಂತೆ: “ಯ ಪ್ರಥಿವಿ ಅಂತರೋ ಯಮಯತಿ ಏಷತ ಆತ್ಮಾ\nಅಂತರ್ಯಾಮಿ ಅಮೃತಃ”. ಅಂದರೆ \"ಪ್ರಥಿವಿಯ ಒಳಗಿದ್ದು ಭಗವಂತ ನಮ್ಮನ್ನು ರಕ್ಷಿಸುತ್ತಿದ್ದರೂ ಕೂಡಾ, ಅದು\nನಮಗೆ ತಿಳಿದಿಲ್ಲ\". ಈ ರೀತಿ ಭೂಮಿಯನ್ನು ಧಾರಣೆ ಮಾಡಿ ರಕ್ಷಿಸುವ ಭಗವಂತನ ಶಕ್ತಿಯನ್ನು ಇಲ್ಲಿ 'ಓಜಸ್ಸು'\nಎಂದಿದ್ದಾರೆ. ಅಂದರೆ ಎಲ್ಲಾ ಅಡೆ-ತಡೆಗಳನ್ನು ನಿಗ್ರಹ ಮಾಡುವ ಶಕ್ತಿ.\nನಮ್ಮಲ್ಲಿ ಸಂಧ್ಯಾವಂದನೆ ಮಾಡುವಾಗ 'ಮನಸ್ಸಿನ ಸ್ನಾನ'ದ ಒಂದು ಕ್ರಮವಿದೆ. ನಮ್ಮ ಸಹಸ್ರಾರದಲ್ಲಿನ ಚಂದ್ರ\nಮಂಡಲದಲ್ಲಿ ಕುಳಿತಿರುವ ಧನ್ವಂತರಿಯ ಕೈಯಲ್ಲಿರುವ ಅಮೃತಕಲಶದಿಂದ ಅಮೃತಧಾರೆ ಕೆಳಕ್ಕೆ ಹರಿದು\nಬರುತ್ತಿರುವುದನ್ನು- ನಾವು ಮಾನಸಿಕವಾಗಿ ಅನುಭವಿಸಿ ಸ್ನಾನ ಮಾಡುವುದು. ಇಲ್ಲಿ ಇಪ್ಪತ್ನಾಲ್ಕು ಬಾರಿ 'ಓಂ-\nವಂ' ಎಂದು ಹೇಳುವುದರಿಂದ ಆ ಚಂದ್ರಮಂಡಲದ ಅಮೃತ ದ್ರವ ಹರಿದು ನಾವು ಒಳಗಿನಿಂದ\nಶುದ್ಧರಾಗುತ್ತೇವೆ. ಇದನ್ನು ಭಗವಂತನಲ್ಲಿ ಮನಸ್ಸನ್ನು ಏಕಾಗ್ರಗೊಳಿಸಿ, ಮಾನಸಿಕವಾಗಿ ಅನುಭವಿಸಿಕೊಂಡು\nಮಾಡಿದಾಗ ಮನಸ್ಸು ಶುದ್ಧವಾಗುತ್ತದೆ. ನಮ್ಮಲ್ಲಿರುವ ಎಲ್ಲಕ್ಕೆಂತ ದೊಡ್ಡ ಕೊಳೆ ನಮ್ಮ ಮನಸ್ಸಿನಲ್ಲಿರುವ\nಪಾಪಪುರುಷ. ಕೆಟ್ಟ ಭಾವನೆ, ಕೆಟ್ಟ ಯೋಚನೆ, ಅಸೂಯೆ, ಹೀಗೆ ಎಲ್ಲವೂ ತುಂಬಿರುವುದು ನಮ್ಮ ಮನಸ್ಸಿನಲ್ಲಿ.\nಅದು ಹೋಗಬೇಕಾದರೆ ಈ ಚಂದ್ರ ಮಂಡಲದ ಅಮೃತ ಕಲಶದಿಂದ ಬರುವ ಅಮೃತ ದ್ರವದಿಂದ\nಸ್ನಾನಮಾಡಬೇಕು. ಇದನ್ನೇ ಕೃಷ್ಣ ಇಲ್ಲಿ “ಸೋಮೋ ಭೂತ್ವಾ ರಸಾತ್ಮಕಃ” ಎಂದ. ಭಗವಂತ ಸೋಮ\nರೂಪದಲ್ಲಿ ಚಂದ್ರನಲ್ಲಿ ತುಂಬಿದ್ದಾನೆ. ಆತ ನೀರಿನ ನಿಯಾಮಕ ಚಂದ್ರನಲ್ಲಿ ಸೋಮನಾಗಿ, ವನಸ್ಪತಿಗಳಲ್ಲಿ\nಜೀವರಸ ತುಂಬಿದ. ನಾವು ಯಾವುದನ್ನು ತಿಂದು ಬದುಕುತ್ತೇವೋ, ಆ ಗಿಡವನ್ನು ರಕ್ಷಿಸಿ ಬೆಳೆಸುವವ-ಚಂದ್ರನಲ್ಲಿ\nತುಂಬಿರುವ ಸೋಮ ರೂಪಿ ಭಗವಂತ.\n",
  "15.14": "ಅಹಮ್‌ ವೈಶ್ವಾನರಃ ಭೂತ್ವಾ ಪ್ರಾಣಿನಾಮ್‌ ದೇಹಮ್‌ ಅಶ್ರಿತಃ ।\n\nಪ್ರಾಣ ಅಪಾನ ಸಮಾಯುಕ್ತಃ ಪಚಾಮಿ ಅನ್ನಮ್‌ ಚತುರ್ವಿಧಮ್‌ -ನಾನು \"ವೈಶ್ವಾನರ'ನಾಗಿ ಜೀವಿಗಳ\nದೇಹದೊಳಗಿದ್ದು ಪ್ರಾಣ-ಅಪಾನರಿಂದೊಡಗೂಡಿ [ತಿನ್ನು ವ, ಚೀಪುವ, ನೆಕ್ಕುವ, ಕುಡಿಯುವ] ನಾಲ್ಕು ಬಗೆಯ\nಆಹಾರವನ್ನು ಕರಗಿಸುತ್ತೇನೆ.\n\nಇಲ್ಲಿ 'ಪಚಾಮ್ಯನ್ನಂ ಚತುರ್ವಿಧಮ್‌' ಎಂದರೆ ನಾಲ್ಕು ಬಗೆಯ ಅನ್ನವನ್ನು ಅರಗಿಸುವೆ\" ಎಂದರ್ಥ. ಅನ್ನವೆಂದರೆ\nಎಲ್ಲಾ ರೀತಿಯ 'ಆಹಾರ'. \"ಪ್ರಾಣಿನಾಂ ದೇಹಮಾಶ್ರಿತಃ\" ಎಂದರೆ 'ಪ್ರಾಣಿ'ಗಳು ತಿನ್ನಬಲ್ಲ ಆಹಾರ ಎಂದರ್ಥ.\nಪ್ರಾಣಿಗಳ ಅಹಾರವನ್ನು ನಾಲ್ಕು ವಿಧಗಳಲ್ಲಿ ವಿಂಗಡಿಸಬಹುದು- ಭಕ್ಷ್ಯ. ಭೋಜ್ಯ, ಲೇಹ್ಯ ಮತ್ತು ಚೋಷ್ಯ. ಭಕ್ಷ್ಯ\nಅಂದರೆ ಅಗಿದು, ಕಡಿದು ತಿನ್ನಲು ಯೋಗ್ಯವಾದುದು (ತಿನ್ನುವುದು); ಭೋಜ್ಯ ಅಂದರೆ ಅಗಿಯದೆಯೇ, ನವಣಿಸಿ\nತಿನ್ನ ಲು ಯೋಗ್ಯವಾದುದು (ಉಣ್ಣುವುದು). ಲೇಹ್ಯ ಅಂದರೆ ನೆಕ್ಕಿ ತಿನ್ನ ಲು ಯೋಗ್ಯವಾದುದು; ಚೋಷ್ಯ ಅಂದರೆ\nಕುಡಿಯಲು ಯೋಗ್ಯವಾದುದು. ಈ ನಾಲ್ಕು ವಿಧದ 'ಅನ್ನ'ವನ್ನು ಸೇವಿಸುವ ಎಲ್ಲಾ ಜೀವಿಗಳ ಜಠರದಲ್ಲಿ ಅಗ್ನಿಯ\nರೂಪದಲ್ಲಿದ್ದು, ನಾಲ್ಕು ಬಗೆಯ ಅನ್ನವನ್ನು ಮೂರು ಬಗೇ(ಸೂಕ್ಷ್ಮ-ಮಧ್ಯ-ಸ್ಥೂಲ)ಯಲ್ಲಿ ವಿಭಾಗಮಾಡಿ, ದೇಹಕ್ಕೆ\nಉಣಬಡಿಸಿ ನಮಗೆ ಬದುಕಲು ವ್ಯವಸ್ಥೆ ಮಾಡಿಸುವವ ವೈಶ್ವಾನರ ರೂಪಿ ಭಗವಂತ.\nನಾವು ಸೇವಿಸುವ ಆಹಾರ ಮಣ್ಣು-ನೀರು-ಬೆಂಕಿಯ ಮಿಶ್ರಣ. ಆಹಾರದಲ್ಲಿನ ಮಣ್ಣಿನ ಸೂಕ್ಷ್ಮ ಭಾಗ ಮೆದುಳಿಗೆ,\nಮಧ್ಯ ಭಾಗ ಮಾಂಸ-ಚರ್ಮಕ್ಕೆ, ಹಾಗೂ ಸ್ಥೂಲ ಭಾಗ ಮಲವಾಗಿ ವಿಸರ್ಜನೆಯಾಗುತ್ತದೆ. ಅದೇ ರೀತಿ ನೀರಿನ\nಸೂಕ್ಷ್ಮ ಭಾಗ ಉಸಿರಾಗಿ, ಮಧ್ಯ ಭಾಗ ನೆತ್ತರಾಗಿ, ಹಾಗೂ ಸ್ಥೂಲ ಭಾಗ ಮೂತ್ರವಾಗಿ ವಿನಿಯೋಗವಾಗುತ್ತದೆ.\nಇನ್ನು ಬೆಂಕಿಯ ಸೂಕ್ಷ್ಮ ಭಾಗ ವಾಕ್‌ ಶಕ್ತಿಯಾಗಿ, ಮಧ್ಯ ಭಾಗ ಅಸ್ಥಿಮಜ್ಜೆಯಾಗಿ , ಸ್ಥೂಲ ಭಾಗ ಹಲ್ಲು ಮತ್ತು\nಅಸ್ಥಿಯಾಗಿ ವಿನಿಯೋಗವಾಗುತ್ತದೆ. ಈ ರೀತಿ ಚಿನ್ನದ ಗಣಿಯಿಂದ ಚಿನ್ನವನ್ನು ಬೇರ್ಪಡಿಸುವುದಕ್ಕಿಂತ\nಕಠಿಣವಾದ ಈ ಕಾರ್ಯವನ್ನು ನಮ್ಮೊಳಗಿದ್ದು ವ್ಯವಸ್ಥಿತ ರೀತಿಯಲ್ಲಿ ಮಾಡಿ, ನಮಗೆ ಜೀವನವನ್ನು ಕೊಡುವವನು\nಆ ಭಗವಂತ. ಭಗವಂತನ ಈ ಕಾರ್ಯಕ್ಕೆ ಸೇವಕ ಪ್ರಾಣ-ಅಪಾನ ಎನ್ನುವ ಪ್ರಾಣದೇವರ ಎರಡು ರೂಪಗಳು.\nಕಠೋಪನಿಷತ್ತಿನಲ್ಲಿ ಹೇಳುವಂತೆ:\nಊರ್ಧ್ವಂ ಪ್ರಾಣಮುನ್ನಯತಿ ಅಪಾನಂ ಪ್ರತ್ಯಗಸ್ಯತಿ.\nಮಧ್ಯೇ ವಾಮನಮಾಸೀನಂ ವಿಶ್ವೇ ದೇವಾ ಉಪಾಸತೇ ॥೨-೨-೩॥\n\nಇಲ್ಲಿ ಪ್ರಾಣ-ಅಪಾನ ಎನ್ನುವ ಪ್ರಾಣದೇವರ ಎರಡು ರೂಪ, ಮಧ್ಯದಲ್ಲಿ(ಹೃದಯದಲ್ಲಿ) ಭಗವಂತನ ವಾಮನ\nರೂಪ. ಇದು ಪಂಚರೂಪಿ ಭಗವಂತನ ಉಪಾಸನೆಗಿಂತ ಭಿನ್ನವಾದ ಉಪಾಸನೆ. ಹೃದಯದ ಮಧ್ಯದಲ್ಲಿದ್ದು,\nನಾವು ಉಂಡ ಆಹಾರವನ್ನು ಜೀರ್ಣಿಸಿ ಬದುಕು ಕೊಡುವವನು-ವಾಮನ ರೂಪಿ ಭಗವಂತ. ಈ ಮನ್ವಂತರದಲ್ಲಿ\nವಾಮನ ದೇವೇಂದ್ರನ ರಕ್ಷಕನಾಗಿರುವ 'ಉಪೇಂದ್ರ'. ಆದ್ದರಿಂದ ನಮ್ಮ ಹೃದಯದಲ್ಲಿರುವ ವಾಮನ ರೂಪಿ\nಭಗವಂತನ ಉಪಾಸನೆ ಈ ಮನ್ವಂತರದಲ್ಲಿ ಬಹಳ ಮುಖ್ಯವಾಗುತ್ತದೆ. ನಮ್ಮೊಳಗೆ ವಾಮನ ರೂಪಿಯಾಗಿರುವ\nಈ ಭಗವಂತನೇ ತ್ರಿವಿಕ್ರಮನಾಗಿ ಭೂಮಿ-ವ್ಯೋಮದಲ್ಲಿ ತುಂಬಿರುವವನು.\n",
  "15.15": "ಸರ್ವಸ್ಯ ಚ ಅಹಮ್‌ ಹೃದಿ ಸನ್ನಿವಿಷ್ಟಃ ಮತ್ತಃ ಸ್ಮೃತಿಃ ಜ್ಞಾನಮ್‌ ಅಪೋಹನಮ್‌ ಚ |\nವೇದೈಃ ಚ ಸರ್ವೈಃ ಅಹಮ್‌ ಏವ ವೇದ್ಯಃ ವೇದಾಂತಕೃತ್‌ ವೇದವಿತ್‌ ಏವ ಚ ಅಹಮ್‌--ಎಲ್ಲಾ ಹೃದಯದಲ್ಲಿ\nನಾನು ನೆಲೆಸಿರುವೆ. ನೆನಪು, ಅರಿವು, ಮರೆವು ಎಲ್ಲಾ ನನ್ನ ಕೊಡುಗೆ. ಎಲ್ಲಾ ವೇದಗಳಿಂದ ಅರಿಯಬೇಕಾದವನು\nನಾನೇ. ವೇದಾಂತ ಸೂತ್ರಗಳ ನೊರೆದವನು, ವೇದಗಳ ಮರ್ಮವನ್ನರಿತವನು ನಾನೇ.\n\n\"ಸರ್ವಸ್ಯ ಚ ಅಹಮ್‌ ಹೃದಿ'- ಭಗವಂತ ಅಹಂ ಶಬ್ದ ವಾಚ್ಯನಾಗಿ ನಮ್ಮೊಳಗೆ ತುಂಬಿದ್ದಾನೆ. ನಮ್ಮ ಹೊರಗಿರುವ\nಭಗವಂತನ ರೂಪಕ್ಕೆ “ಅಹಃ' ಎಂದರೆ, ನಮ್ಮೊಳಗಿನ ಆತನ ರೂಪಕ್ಕೆ “ಅಹಂ' ಎನ್ನುತ್ತಾರೆ. ನಮ್ಮೊಳಗಿರುವ\nಭಗವಂತ ಸದಾ ನಮ್ಮೊಂದಿಗಿದ್ದು, ನಮ್ಮನ್ನು ರಕ್ಷಿಸುತ್ತಿರುತ್ತಾನೆ. ಸಾವಿನಲ್ಲಿ ಸ್ಥೂಲ ಶರೀರವನ್ನು ಬಿಟ್ಟು\nಹೊರಹೋಗುವಾಗ ಕೂಡಾ ಭಗವಂತ ನಮ್ಮೊಂದಿಗಿರುತ್ತಾನೆ. ಆತ ನಮ್ಮನ್ನು ಒಂದು ಕ್ಷಣ ಬಿಟ್ಟಿರುವುದಿಲ್ಲ.\nಆತನ ನೆಲೆ ನಮ್ಮ ಲಿಂಗಶರೀರದೊಳಗಿರುವ ಸ್ವರೂಪದ ಆತ್ಮ. ಈ ಆತ್ಮನೇ “ಅಹಂ'. ಇಂತಹ ಭಗವಂತನ\nಪ್ರಜ್ಞೆ ನಮಗಿದ್ದರೆ “ನಾನು ಮಾಡಿದೆ' ಎನ್ನುವ ಅಹಂಕಾರ ನಮ್ಮನ್ನು ಕಾಡದು.\nಕಠೋಪನಿಷತ್ತಿನಲ್ಲಿ ಹೇಳುವಂತೆ: “ಅಂಗುಷ್ಠಮಾತ್ರಃ ಪುರುಷೋ$ನ್ತರಾತ್ಮಾ ಸದಾ ಜನಾನಾಂ ಹೃದಯೇ\nಸನ್ನಿವಿಷ್ಟಃ ...?1೨-೩-೭| ಎಲ್ಲಾ ಜೀವರ ಒಳಗೂ ಅಂಗುಷ್ಠಮಾತ್ರನಾಗಿ ಎಂದೆಂದೂ ದುಃಖದ ಲೇಪವಿಲ್ಲದೆ\nನಿರ್ಲಿಪ್ತನಾಗಿ ಭಗವಂತ ತುಂಬಿದ್ದಾನೆ. ಮಧ್ವಾಚಾರ್ಯರು ಕಠೋಪನಿಷತ್ತಿಗೆ ಭಾಷ್ಯ ಬರೆಯುತ್ತ ಹೇಳುತ್ತಾರೆ:\nನಮೋ ಭಗವತೇ ತಸೆ ಟ್ಟ ಸರ್ವತಃ ಪರಮಾಯ ತೇ।\nಸರ್ವಪ್ರಾಣಿಹೃದಿಸ್ಥಾಯ ವಾಮನಾಯ ನಮೋ ನಮಃ ॥ಸರ್ವಮೂಲ॥\nಇಲ್ಲಿ-ಎಲ್ಲರ ಹೃದಯ ಅಂತರ್ಯಾಮಿಯಾಗಿರುವ ಭಗವಂತನ ರೂಪ “ವಾಮನ' ರೂಪ ಎನ್ನುವ ಸುಳಿವು ನಮಗೆ\nಸಿಗುತ್ತದೆ. ಆದ್ದರಿಂದ ಉಪಾಸನೆಯಲ್ಲಿ ನಾವು ನಮ್ಮ ಅಂತರ್ಗತ ಭಗವಂತನನ್ನು ವಾಮನ ರೂಪದಲ್ಲಿ\nಉಪಾಸನೆ ಮಾಡಬೇಕು.\n“ಮತ್ತಃ ಸ್ಮೃತಿರ್ಜ್ಯಾನಮಪೋಹನಂ'”-ನಮಗೆ ಸ್ಮರಣಶಕ್ತಿಯನ್ನು ಕೊಡುವವನು ಆ ಭಗವಂತ. ಜ್ಞಾನ ಬರುವುದೂ\nಭಗವಂತನಿಂದ, ಬಂದ ಜ್ಞಾನ ನೆನಪಿನಲ್ಲಿರುವುದೂ ಭಗವಂತನಿಂದ. ಕೇನೋಪನಿಷತ್ತಿನಲ್ಲಿ ಹೇಳುವಂತೆ:\nಅಥಾಧ್ಯಾತ್ಮಂ ಯದ್ದೇತದ್ಗಚ್ಛತೀವ ಚ ಮನೋಽನೇನ ಚೈತದುಪಸ್ಮರತ್ಯಭೀಕ್ವಂ ಸಂಕಲ್ಪಃ ॥ ೪-೫ ॥ ನಮಗೆ\nನೆನಪಿನ ಶಕ್ತಿಯನ್ನು ಕೊಡುವ ಭಗವಂತನ ಅನಿರುದ್ಧ ರೂಪದ ಉಪಾಸನೆ ಇದಾಗಿದೆ. ಹೇಗೆ ನೆನಪಿನ ಶಕ್ತಿ\nಕೊಡುತ್ತಾನೋ ಹಾಗೇ ಮರೆಯುವಂತೆ ಮಾಡುವವನೂ ಅವನೇ! ಕೆಲವೊಮ್ಮೆ ಅಪರೋಕ್ಷ ಜ್ಞಾನಿಗಳೂ ಕೂಡಾ\nಭಗವಂತನನ್ನು ಮರೆತುಬಿಡುತ್ತಾರೈಭಗವಂತ ಮರೆಯುವಂತೆ ಮಾಡುತ್ತಾನೆ). ಇದಕ್ಕೆ ದೃಷ್ಟಾಂತ\nಭಾಗವತದಲ್ಲಿ ಬರುವ ಗರ್ಗಾಚಾರ್ಯರ ಕಥೆ. ಭಗವಂತನಿಗೆ “ಕೃಷ್ಣ' ಎಂದು ನಾಮಕರಣ ಮಾಡಿ, ಕೃಷ್ಣನ\nಭಕ್ತರಾಗಿದ್ದ ಗರ್ಗಾಚಾರ್ಯರು, ಯಾವುದೋ ಒಂದು ಕೆಟ್ಟ ಸನ್ನಿವೇಶದಲ್ಲಿ ಎಲ್ಲವನ್ನೂ ಮರೆತು, “ಕೃಷ್ಣನನ್ನು\nಕೊಲ್ಲುವ ಮಗ ಹುಟ್ಟಬೇಕು' ಎಂದು ತಪಸ್ಸು ಮಾಡುತ್ತಾರೆ! ಎಂಥಾ ವಿಪರ್ಯಾಸ. ಆದರೆ ಇದೆಲ್ಲವೂ ಆ\nಭಗವಂತನ ಲೀಲೆ. ಆತನ ಲೀಲೆಯ ಹಿಂದಿರುವುದು ದ್ವೇಷವಲ್ಲ-ಕೇವಲ ಕಾರುಣ್ಯ.\nಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ ಸಮಸ್ತ ವೇದಗಳಿಂದ ಅರಿಯಬೇಕಾದವನು ನಾನು” ಎಂದು. ವೇದದ ಪ್ರತಿಯೊಂದು\nಪದವೂ ಭಗವದ್‌ ಪರವಾಗಿದೆ ಎನ್ನುವುದನ್ನು ಬ್ರಹ್ಮಸೂತ್ರ ಸ್ಪಷ್ಟವಾಗಿ ಹೇಳುತ್ತದೆ. ವೇದಾಂತ ಎಂದರೆ\nಉಪನಿಷದ್‌ ಎಂದು ಕೆಲವರು ಹೇಳುವುದುಂಟು. ಆದರೆ ವೇದಾಂತ ಅಂದರೆ 'ವೇದದ ನಿರ್ಣಯ'-ಅದೇ\nಬ್ರಹ್ಮಸೂತ್ರ. ಇದು ಸಮಸ್ತ ವೇದವನ್ನು ಸಮನ್ವಯ ಮಾಡಿ ಹೇಳುವ ಗ್ರಂಥ. ವೇದ ಅನಾದಿನಿತ್ಯ, ವೇದದ\nಮರ್ಮವನ್ನು ಪೂರ್ಣ ತಿಳಿದವನು ಆ ಭಗವಂತನೊಬ್ಬನೆ.\n“ವೇದೈಶ್ಚ ಸರ್ವೈರಹಮೇವ ವೇದ್ಯೋ” ಎನ್ನುವಲ್ಲಿ ಚ-ಕಾರವನ್ನು ಮತ್ತು ಏವ-ಕಾರವನ್ನು ಬಳಸಿದ್ದಾರೆ. ಇಲ್ಲಿ ಚ-\nಕಾರದಿಂದಾಗಿ ಈ ಸಾಲು ಎರಡು ಸಂದೇಶವನ್ನು ಕೊಡುತ್ತದೆ. ಒಂದು ಮುಖ್ಯಾರ್ಥ ಇನ್ನೊಂದು ಅಮುಖ್ಯಾರ್ಥ.\n\n“ಭಗವಂತ ವೇದಗಳಿಂದಲೇ ವೇದ್ಯ' ಎನ್ನುವುದು ಮುಖ್ಯಾರ್ಥ. ಪಂಚಮ ವೇದವೆನಿಸಿರುವ ಪುರಾಣ ಗ್ರಂಥಗಳು,\nವೇದಾಂತ, ಮಹಾಭಾರತ, ರಾಮಾಯಣ ಇತ್ಯಾದಿಗಳಿಂದಲೂ ಭಗವಂತ ವೇದ್ಯ-ಎನ್ನು ವುದು ಅಮುಖ್ಯಾರ್ಥ.\nಇದಲ್ಲದೆ ಸ್ಮೃತಿಗಳಿವೆ-ಆದರೆ ಅದನ್ನು ಪ್ರಮಾಣವೆಂದು ಸ್ವೀಕಾರ ಮಾಡಲು ಸಾಧ್ಯವಿಲ್ಲ. ಏಕೆಂದರೆ\nಸ್ಮೃತಿಗಳನ್ನು ಆಯಾ ಕಾಲದ ರಾಜರುಗಳು ತಮ್ಮ ವಿದ್ವಾಂಸರಿಂದ ಆಯಾ ಕಾಲಕ್ಕನುಗುಣವಾಗಿ\nಬರೆಸಿದ್ದರಿಂದ, |, ಅವು. ಸಂವಿಧಾನವಿದ್ದಂತೆ. ಅಲ್ಲಿ ಆಯಾಕಾಲದ ಸಮಾಜಧರ್ಮ ಜೊತೆಯಾಗಿ\nಬಂದಿರುವುದರಿಂದ ಅದು ಸಾರ್ವಕಾಲಿಕ ಸತ್ಯವಾಗಿರಬೇಕೆಂದೇನೂ ಇಲ್ಲ. ಸಾರ್ವಕಾಲಿಕ ಸನಾತನ ಸತ್ಯ\nವೇದ ಮಾತ್ರ.\n“ಅಹಮೇವ ವೇದಃ” ಎನ್ನುವಲ್ಲಿ ವೇದಗಳಿಂದ ತಿಳಿಯಲ್ಪಡುವವನು ನಾನೊಬ್ಬನೇ ಎನ್ನುವುದು ಮುಖ್ಯಾರ್ಥ.\nಅಮುಖ್ಯವಾಗಿ ಇದು ಭಗವಂತನ ಪಾರಮ್ಯಕ್ಕೆ ಪೂರಕವಾದ ವಿಷಯಗಳನ್ನೂ ಹೇಳುತ್ತದೆ. ಇಲ್ಲಿ “ವೇದಗಳಿಂದ\nತಿಳಿಯಲ್ಬ ಡುವವನು ನಾನೊಬ್ಬನೇ” ಎಂದು ಹೇಳುವುದರ ಮೂಲಕ “ಬಹುದೇವತಾ ವಾದವನ್ನು ಕೃಷ್ಣ\nತಳ್ಳಿ ಹಾಕಿದ. ಭಗವಂತ ಒಬ್ಬನೇ ಎನ್ನು ವುದನ್ನು ವೇದ ಸಾರಿ ಹೇಳುತ್ತದೆ. ಇದಕ್ಕೆ ಬೇರೆ ಪ್ರಮಾಣ ಬೇಕಾಗಿಲ್ಲ.\n“ವೇದಾಂತಕೃದ್‌ ವೇದವಿದೇವ ಚಾಹಮ್‌”ಎನ್ನುವಲ್ಲಿ ಕೃಷ್ಣ “ವೇದದ ಪೂರ್ಣ ಅರ್ಥ ತಿಳಿದಿರುವುದು\nನನಗೊಬ್ಬನಿಗೇ” ಎಂದ. ಭಾಗವತದಲ್ಲಿ ಬರುವ ಉದ್ಭವಗೀತೆಯಲ್ಲಿ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ:\n\nಕಿಂ ವಿಧತ್ತೇ ಕಿಮಾಚಷ್ಟೇ ಕಿಮನೂದ್ಯ ವಿಕಲ್ಪಯೇತ್‌ |\n\nಇತ್ಯಸ್ಯಾ ಹೃದಯಂ ಲೋಕೇ ನಾನ್ಯೋ ಮದ್ವೇದ ಕಶ್ಚನ ॥| ೧೧-೨೧-೪೨||\n\nಮಾಂ ವಿಧತ್ತೇಽಭಿಧತ್ತೇ ಮಾಂ ವಿಕಲ್ಫ್ಯಾ ಪೋಹ್ಯತೇ ತ್ವಹಂ |\n\nಏತಾವಾನ್ಸ ರ್ವವೇದಾರ್ಥಃ ಶಬ್ದ ಆಸ್ಥಾಯ ಮಾಂಭಿದಾಂ |\n\nಮಾಯಾಮಾತ್ರಮನೂದ್ಯಾಂತೇ ಪ್ರತಿಷಿಧ್ಯ ಪ್ರಸೀದತಿ |೧೧-೨೧-೪೩॥\nವೇದದ ಪ್ರತಿಯೊಂದು ಶಬ್ದವೂ ಭಗವಂತನನ್ನು ಹೇಳುತ್ತದೆ ಎಂದು ಇಲ್ಲಿ ಕೃಷ್ಣ ಸ್ಪಷ್ಟವಾಗಿ ವಿವರಿಸಿದ್ದಾನೆ. ಆದರೆ\nನಾವು ವೇದವನ್ನು ಮೇಲ್ನೋಟದಲ್ಲಿ ನೋಡಿದಾಗ- ವೇದ 'ಕರ್ಮ-ಬೋಧಕ', ಪ್ರತಿಯೊಂದು ಪದವೂ\n“ಕರ್ಮವಾಚಕ' ಪದ ಎನ್ನುವಂತೆ ಕಾಣುತ್ತದೆ. ಆದರೆ ಆ ರೀತಿ ತಿಳಿಯುವುದು ತಪ್ಪು. ಕ್ರಿಯೆ ಮಾಡುವುದರಿಂದ\nಮನಸ್ಸು ಸ್ವಚ್ಛವಾಗುತ್ತದೆ, ಶುದ್ಧ ಮನಸ್ಸಿಗೆ ಜ್ಞಾನ ಬಹುಬೇಗ ಹತ್ತುತ್ತದೆ. ಇದರಿಂದ ಭಗವಂತನನ್ನು ತಿಳಿಯಲು\nಸಾಧ್ಯವಾಗುತ್ತದೆ. ಆದ್ದರಿಂದ ವೇದದಲ್ಲಿ ಬರುವ ಪ್ರತಿಯೊಂದು ಕ್ರಿಯೆಯೂ ಹೇಳುವುದು ಭಗವಂತನನ್ನು. ವೇದ\nಒಂದು ಕಡೆ ಈ ಕ್ರಿಯೆ ಮಾಡು ಎಂದರೆ ಇನ್ನೊಂದು ಕಡೆ ಇನ್ನೊಂದು ಕ್ರಿಯೆಯನ್ನು ಮಾಡಬೇಡ ಎನ್ನುತ್ತದೆ.\nಉದಾಹರಣೆಗೆ “ಸೋಮಪಾನ ಮಾಡು-ಸುರಪಾನ ಮಾಡಬೇಡ” ಎನ್ನುತ್ತದೆ. ವೇದ. ಇದರ ಅರ್ಥ :\nಸೋಮಪಾನ ಅಧ್ಯಾತ್ಮ ಚಿಂತನೆಗೆ ಮನಸ್ಸನ್ನು ಅಣಿಗೊಳಿಸುತ್ತದೆ, ಅದರಿಂದ ಭಗವಂತನನ್ನು ತಿಳಿಯಬಹುದು;\nಸುರಪಾನ ಮಾಡಿದರೆ ಅದರಿಂದ ಬುದ್ಧಿ ಕೆಡುತ್ತದೆ ಅದು ಭಗವಂತನಿಂದ ನಮ್ಮನ್ನು ದೂರ ಮಾಡುತ್ತದೆ. ಹೀಗೆ\nವೇದದಲ್ಲಿ ಹೇಳುವ ಪ್ರತಿಯೊಂದು ಕ್ರಿಯೆಯೂ ಅಂತತಃ ಭಗವಂತನನ್ನೇ ಹೇಳುತ್ತವೆ. ಕೆಲವು ಕಡೆ ವೇದ ಸೃಷ್ಟಿ-\nಸಂಹಾರದ ಬಗ್ಗೆ ಹೇಳುತ್ತದೆ; ಸೃಷ್ಟಿಯ ಕ್ರಮವನ್ನು ಹೇಳುತ್ತದೆ. ಇದು “ಭಗವಂತ ಈ ರೀತಿ ಸೃಷ್ಟಿ ಕ್ರಿಯೆಯನ್ನು\nಮಾಡುತ್ತಾನೆ” ಎಂದು ಭಗವಂತನನ್ನೇ ಹೇಳುವ ಸಾಲುಗಳು.\n\nವೇದ ಸೂಕ್ತಗಳು ಒಂದೊಂದು ಕಡೆ ಒಂದೊಂದು ದೇವತೆಗಳ ಹೆಸರನ್ನು ಹೇಳುತ್ತವೆ. ಒಂದು ಕಡೆ ಅಗ್ನಿ,\nಇನ್ನೊಂದು ಕಡೆ ಇಂದ್ರ, ಮತ್ತೊಂದು ಕಡೆ ಸರಸ್ವತಿ, ಹೀಗೆ. ಇಲ್ಲಿ ನಮಗೆ ಇದು ಬಹುದೇವತಾ ವಾದವಾಗಿ\nಕಾಣಬಹುದು. ಆದರೆ ಕೃಷ್ಣ ಹೇಳಿದ “ಅಭಿಧತ್ತೇ ಮಾಂ” ಎಂದು. ಉದಾಹರಣೆಗೆ “ಆತ್ಮನಃ ಆಕಾಶಃ\nಸಂಭೂತಃ”. ಅಹಂಕಾರ ತತ್ವದಿಂದ ಆಕಾಶ ದೇವತೆ-ಗಣಪತಿ ಹುಟ್ಟಿದ. ಆಕಾಶ ಸೃಷ್ಟಿ ಎಂದರೆ ಇದ್ದ\nಅಂತರಿಕ್ಷದಲ್ಲಿ, ಒಂದು ಆವರಣ(ವಾತಾವರಣ) ಸೃಷ್ಟಿ. ಅದರ ಅಭಿಮಾನಿ ದೇವತೆಯಾಗಿ ಗಣಪತಿ\nಹುಟ್ಟಿದ. ಗಣಪತಿಯೊಳಗೆ ಆಕಾಶದಲ್ಲಿ ತುಂಬಿರುವ ಭಗವಂತ-ಆಕಾಶನಾಮಕನಾಗಿ ಅವತರಿಸಿದ. ಹೀಗೆ\nಪ್ರತಿಯೊಂದು ವೇದ ಶ್ಲೋಕವೂ ಕೂಡಾ ಅಂತತಃ ಹೇಳುವುದು ಭಗವಂತನನ್ನು.\n\nವೇದದಲ್ಲಿ. ಬರುವ ಪ್ರತಿಯೊಂದು ಶಬ್ದಗಳು ಭಗವಂತನನ್ನು ಹೇಗೆ ಹೇಳುತ್ತವೆ ಎನ್ನುವುದನ್ನು ಈ\nಉದಾಹರಣೆಯಲ್ಲಿ ಕಾಣಬಹುದು. ಉದಾಹರಣೆ: 'ಅಗ್ನಿ'. ಅ-ಗ-ನಿ = ಅಗ್ನಿ. ಚಲನೆ ಇಲ್ಲದ ವಸ್ತುವಿಗೆ(ಅಗ) ಚಲನೆ\nಕೊಡುವವನು-ಅಗ-ನಿ. ಭಗವಂತ ಇಡೀ ವಿಶ್ವಕ್ಕೆ ಚಲನೆ ಕೊಡುವವ ಆದ್ದರಿಂದ ಆತ ಅಗ್ನಿ.\n\nವೇದದಲ್ಲಿರುವ ಒಂದೊಂದು ಅಕ್ಷರವೂ ಭಗವಂತನ ನಾಮ. ಉದಾಹರಣೆಗೆ 'ಅ'.\nಅಂಅಜಃ(ಹುಟ್ಟಿಲ್ಲದವನು); ಅಂಅನಂತಃ(ಸಾವಿಲ್ಲದವನು). ಹಾಗೇ 'ಆ'. ಆ-ಆದಿಃ(ಎಲ್ಲಕ್ಕೆಂತ ಮೊದಲಿದ್ದವನು);\nಆ-ಂಆನಂದ।; ಇತ್ಯಾದಿ. ವರಾಹ ಪುರಾಣದಲ್ಲಿ ವೇದವ್ಯಾಸರು ಹೇಳುತ್ತಾರೆ: \"ಯಾವಂತಿ ಪಟಿಥಾನಿ ತಾವಂತಿ\nಹರಿನಾಮಂತಿ ಪಟಿಥಾನಿ ನಾಸಂಶಯಹ”\" ಎಂದು. ಋಗ್ವೇದದಲ್ಲಿ 4 ಲಕ್ಷದ 32 ಸಾವಿರ ಅಕ್ಷರಗಳಿವೆ. ಆದ್ದರಿಂದ\nಪ್ರಾಚೀನರ ಪ್ರಕಾರ ಒಮ್ಮೆ ಋಗ್ವೇದ ಓದಿದರೆ 4 ಲಕ್ಷದ 32 ಸಾವಿರ ಭಗವಂತನ ನಾಮವನ್ನು ಹೇಳಿದ\nಹಾಗಾಗುತ್ತದೆ. ಒಟ್ಟಿನಲ್ಲಿ ವೇದದ ಅಕ್ಷರದಿಂದ ಭಗವಂತನನ್ನು ಕಾಣುವುದು; ಪದದಿಂದ ಭಗವಂತನನ್ನು\nಕಾಣುವುದು; ವಾಕ್ಯದಿಂದ ಭಗವಂತನನ್ನು ಕಾಣುವುದು ಮತ್ತು ಪ್ರಕರಣದಲ್ಲಿ ಭಗವಂತನನ್ನು ಕಾಣುವುದು. ಹೀಗೆ\nವೇದವನ್ನು ಬಿಡಿಸಿ ನೋಡಿದಾಗ ಮಾತ್ರ ನಮಗೆ ಅಲ್ಲಿರುವ ಸಂದೇಶ ತಿಳಿಯುತ್ತದೆ. ಇಲ್ಲದಿದ್ದರೆ ಎಲ್ಲವೂ\nಲೌಕಿಕವಾಗಿ ಕಾಣುತ್ತದೆ. ಆದರೆ ಎಲ್ಲವನ್ನೂ ನಾವು ತಿಳಿಯಲು ಸಾಧ್ಯವಿಲ್ಲ(ನಾನ್ಯೋ ಮದ್ವೇದ ಕಶ್ಚನ). ಅದನ್ನು\nಪೂರ್ಣವಾಗಿ ತಿಳಿದವನು ಆ ಭಗವಂತನೊಬ್ಬನೇ.\n\nಮುಂದಿನ ಮೂರು ಶ್ಲೋಕಗಳು ಭಾರತೀಯ ತತ್ವಶಾಸ್ತ್ರದ ಚಿಂತನಾಕ್ರಮದ ಸಾರ. ಇವು ವಿಶ್ವ ಮತ್ತು\nವಿಶ್ವಾತ್ಮನ ಅನುಸಂಧಾನವನ್ನು ವಿವರಿಸುವ ಶ್ಲೋಕಗಳು.\n",
  "15.16": "ದ್ವಾವಿಮೌ ಪುರುಷೌ ಲೋಕೇ ಕ್ಷರಃ ಚ ಅಕ್ಷರಃ ಏವ ಚ |\nಕ್ಷರಃ ಸರ್ವಾಣಿ ಭೂತಾನಿ ಕೂಟಸ್ಥಃ ಅಕ್ಷರಃ ಉಚ್ಯತೇ--ಲೋಕದಲ್ಲಿ ಈ ಎರಡು ಬಗೆಯ ಪುರುಷರು: ಕ್ಷರಪುರುಷ\nಮತ್ತು ಅಕ್ಷರಪುರುಷ. ಬ್ರಹ್ಮಾದಿ ಸಮಸ್ತ ಜೀವರೂ ಕ್ಷರಪುರುಷರು. ಈ ಚರಾಚರದ ಕೂಟವನ್ನು ಕೂಡಿಸಿಟ್ಟ ಚಿತ್‌\nಪ್ರಕೃತಿಯೇ ಅಕ್ಷರ ಪುರುಷಳೆನ್ನಿಸಿದ್ದಾಳೆ.\n\nಈ ಚೇತನಾ ಪ್ರಪಂಚದಲ್ಲಿ ಎರಡು ಬಗೆಯ ಪುರುಷರಿದ್ದಾರೆ. ಒಂದು ಕ್ಷರಪುರುಷ ಮತ್ತು ಇನ್ನೊಂದು\nಅಕ್ಷರಪುರುಷ. [ಇಲ್ಲಿ ಪುರುಷ ಎಂದರೆ ಗಂಡಸು ಎನ್ನುವ ಅರ್ಥವಲ್ಲ. ಈ ಬಗ್ಗೆ ವಿಶೇಷವಾಗಿ ಹಿಂದೆ ಅನೇಕ ಬಾರಿ\nಚರ್ಚಿಸಿದ್ದೇವೆ]. ಒಂದು ದಿನ ಬಿದ್ದುಹೋಗುವ ಶರೀರ ಉಳ್ಳವರು ಕ್ಷರಪುರುಷರು. ಬ್ರಹ್ಮಾದಿ ಸಮಸ್ತ ಜೀವರೂ\nಕೂಡಾ ಕ್ಷರಪುರುಷರು. ಬ್ರಹ್ಮಾದಿ ಸಮಸ್ತ ದೇವತೆಗಳೂ ಕೂಡಾ ಮೋಕ್ಷವನ್ನು ಸೇರುವಾಗ ತಮ್ಮ ಶರೀರ\nಸಮೇತರಾಗಿ ಹೋಗುವಂತಿಲ್ಲ. ಚತುರ್ಮುಖ ಬ್ರಹ್ಮನ ಆಯುಸ್ಸು ಒಂದು ಕಲ್ಬ(೩೧,೧೦೪ ಸಾವಿರ ಕೋಟಿ\nಮಾನವ ವರ್ಷ). ಆ ನಂತರ ಆತನ ಶರೀರ ಕೂಡಾ ಬಸ್ಮವಾಗುತ್ತದೆ. ಇದನ್ನು ಈಶೋಪನಿಷತ್ತಿನಲ್ಲಿ ಹೀಗೆ\nವಿವರಿಸಿದ್ದಾರೆ: “ವಾಯುರನಿಲಮ್‌ ಅಮೃತಮ್‌ ಅಥೇದಂ ಭಸ್ಮಾಂತಂ ಶರೀರಂ ॥ ೧೭|. “ಭಗವಂತನಿಗೆ\nಅಧಿಷ್ಠಾನವಾಗಿ ನಿಂತಿರುವ ಪ್ರಾಣ ದೇವರು ಅಮೃತರು. ಆದರೂ ಕೂಡಾ, ಒಂದು ದಿನ ಅವರ ದೇಹ\nಬಸ್ಮವಾಗಲೇ ಬೇಕು” ಎಂದು. ಹೀಗೆ ಸಮಸ್ತ ದೇವತೆಗಳು, ಜೀವಜಾತಗಳು-ಕ್ಷರಪುರುಷರು.\n\nನಾಶವಿಲ್ಲದ ಜ್ಞಾನಾನಂದಮಯ ಸ್ವರೂಪಭೂತವಾದ ದೇಹವುಳ್ಳ ಶ್ರೀಲಕ್ಷ್ಮಿ ಅಕ್ಷರಪುರುಷಳು. ಸಮಸ್ತ\nಕ್ಷರಪುರುಷರೂ ಮೋಕ್ಷದಲ್ಲಿ ಅಕ್ಷರರಾಗುತ್ತಾರೆ. ಆದರೆ ಲಕ್ಷ್ಮಿ ಸದಾ ಅಕ್ಷರಳು. ಇಲ್ಲಿ ಲಕ್ಷ್ಮಿಯನ್ನು ಕೂಟಸ್ಥಳು\nಎಂದು ವರ್ಣಿಸಿದ್ದಾರೆ. ಕೂಟ ಎಂದರೆ “ಕೂಡುವುದು'. ಜೀವ ಮತ್ತು ಶರೀರದ ಕೂಡುವಿಕೆಗೆ ಕಾರಣಳಾದವಳು\nತಾಯಿ-ಶ್ರೀಲಕ್ಷ್ಮಿ. ಸದಾ ನಿರ್ಲಿಪ್ತಳಾಗಿ, ಯಾವುದೇ ಲೇಪವಿಲ್ಲದೆ, ಪ್ರಪಂಚವನ್ನು ವ್ಯವಸ್ಥೆಗೊಳಿಸಿದ ಶಕ್ತಿ -\nಜಗನ್ಮಾತೆ ಶ್ರೀಲಕ್ಷ್ಮಿ. ಇವಳು ಅಕ್ಷರಪುರುಷಳು.\n",
  "15.17": "ಉತ್ತಮಃ ಪುರುಷಃ ತು ಅನ್ಯಃ ಪರಮ ಆತ್ಮಾ ಇತಿ ಉದಾಹೃತಃ |\nಯಃ ಲೋಕತ್ರಯಮ್‌ ಆವಿಶ್ಯ ಬಿಭರ್ತಿ ಅವ್ಯಯಃ ಈಶ್ವರಃ -ಈ ಎರಡಕ್ಕೂ ಮಿಗಿಲಾದವನು ಪುರುಷೋತ್ತಮ.\nಅವನನ್ನೆ ೀ ಪರಮಾತ್ಮ ಎನ್ನು ತ್ತಾರೆ. ಅಳಿವಿರದ ಆ ಪರಮೇಶ್ವರನೇ ಮೂರು ಲೋಕದೊಳಗಿದ್ದು ಸಲಹುತ್ತಾನೆ.\n\nಕ್ಷರ ಮತ್ತು ಅಕ್ಷರವನ್ನು ಮೀರಿ ನಿಂತಿರುವ ಪರಮಪುರುಷ ಆ ಭಗವಂತ. ಅವನನ್ನೇ “ಪರಮಾತ್ಮ' ಎಂದು\nಕರೆಯುತ್ತಾರೆ. ಯಾರು ಈ ಮೂರು ಲೋಕದೊಳಗೆ, (ಭೂಃ ಭುವಃ ಸ್ವಃ ಅಥವಾ ಇಡೀ ಬ್ರಹ್ಮಾಂಡ-ಇದನ್ನು ಏಳು\nಅಥವಾ ಹದಿನಾಲ್ಕು ಲೋಕವನ್ನಾ ಗಿಯೂ ವಿಭಾಗ ಮಾಡಿ ಹೇಳುತ್ತಾರೆ.) ತುಂಬಿ ಧಾರಣೆ ಮಾಡಿ\nರಕ್ಷಿಸುತ್ತಿದ್ದಾನೋ ಅವನು ಸರ್ವಶಕ್ತ(ಈಶ್ವರ)ನಾದ ಭಗವಂತ.\n",
  "15.18": "ಯಸ್ಮಾತ್‌ ಕ್ಷರಮ್‌ ಅತೀತಃ ಅಹಮ್‌ ಅಕ್ಷರಾತ್‌ ಅಪಿ ಚ ಉತ್ತಮಃ |\nಅತಃ ಅಸ್ಮಿ ಲೋಕೇ ವೇದೇ ಚ ಪ್ರಥಿತಃ ಪುರುಷ ಉತ್ತಮಃ -ನಾನು ಕ್ಷರವನ್ನು ಮೀರಿನಿಂತವನು.\nಅಕ್ಷರಕ್ಕಿಂತಲೂ ಹಿರಿಯನು. ಅದಕೆಂದೇ ಲೋಕದಲ್ಲೂ ವೇದದಲ್ಲೂ 'ಪುರುಷೋತ್ತಮ' ಎಂದೇ ಹೆಸರಾಗಿದ್ದೇನೆ.\n\nಹಿಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ “ಯಾರು ಕ್ಷರಾಕ್ಷರಗಳಿಂದ ಅತೀತನೋ ಅವನು ಪುರುಷೋತ್ತಮ” ಎಂದು ಹೇಳಿದ ಕೃಷ್ಣ,\nಇಲ್ಲಿ ನೇರವಾಗಿ “ಆ ಬೇರೆಯಾದ ಪುರುಷೋತ್ತಮ ನಾನೇ” ಎಂದು ಸ್ಪಷ್ಟವಾಗಿ ಹೇಳುತ್ತಾನೆ. ಮಧ್ವಾಚಾರ್ಯರು\nವಿಷ್ಣುತತ್ವ ನಿರ್ಣಯದ ಮಂಗಳಾಚರಣೆಯಲ್ಲಿ ಹೇಳುತ್ತಾರೆ: “ಸದಾಗಮೈಕ ವಿಜ್ಞೇಯಂ, ಸಮತೀತ ಕ್ಷರಾಕ್ಷರಂ,\nನಾರಾಯಣಂ ಸದಾ ವಂದೇ, ನಿರ್ದೋಷ ಅಶೇಷ ಸದ್ಗುಣಂ” ಎಂದು. ಇಲ್ಲಿ ಕ್ಷರ ಮತ್ತು ಅಕ್ಷರದಿಂದ\nಅತೀತನಾದ ಭಗವಂತನನ್ನು ಅವರು “ಸಮತೀತ ಕ್ಷರಾಕ್ಷರಂ” ಎಂದು ಕರೆದಿದ್ದಾರೆ.\nಈ ಶ್ಲೋಕದಲ್ಲಿ ಕ್ಷರದಿಂದ ಅತೀತ ಮತ್ತು ಅಕ್ಷರದಿಂದ ಉತ್ತಮ ಎಂದಿದೆ. ಇಲ್ಲಿ ಅತೀತ ಎಂದರೆ ಉತ್ತಮ.\nಆದರೂ ಅತೀತ ಮತ್ತು ಉತ್ತಮ ಎಂದು ಎರಡು ಪದ ಬಳಕೆ ಮಾಡಿದ್ದಾರೆ. ಇದು ಒಂದು ವಿಶೇಷ ಅರ್ಥವನ್ನು\nಕೊಡುತ್ತದೆ. ಕ್ಷರಪುರುಷನ ಅಸ್ತಿತ್ವದ ವ್ಯಾಪ್ತಿ ಈ ಬ್ರಹ್ಮಾಂಡದ ಒಳಗೆ. ಆದರೆ ಲಕ್ಷ್ಮೀ ನಾರಾಯಣರು ಈ\nಬ್ರಹ್ಮಾಂಡವನ್ನು ಮೀರಿ ನಿಂತವರು. ಇದನ್ನು 'ಅತೀತ' ಪದ ವಿವರಿಸುತ್ತದೆ. ಭಗವಂತ ಅಕ್ಷರಳಾದ\nಲಕ್ಷ್ಮಿಗಿಂತಲೂ ಉತ್ತಮ. ಈ ಶ್ಲೋಕದಲ್ಲಿ “ಅಪಿ' ಮತ್ತು 'ಚ-ಕಾರವನ್ನು' ಒಟ್ಟಿಗೆ ಬಳಸಲಾಗಿದೆ. ಇದು\nಭಗವಂತನ ಸರ್ವಶ್ರೇಷ್ಠತ್ವವನ್ನು ಹೇಳುತ್ತದೆ. ಆತನಿಗಿಂತ ಶ್ರೇಷ್ಠವಾದ ತತ್ವ ಇನ್ನೊಂದಿಲ್ಲ.\nಪುರುಷೋತ್ತಮ ಪದದ ಎಲ್ಲಾ ಮುಖದ ಅರ್ಥ ಕೇವಲ ಭಗವಂತನಲ್ಲಿ ಮಾತ್ರ ಅನ್ವಯವಾಗುತ್ತದೆ. ಕೃಷ್ಣ\nಹೇಳುತ್ತಾನೆ: “ಲೋಕದಲ್ಲಿ ಮತ್ತು ವೇದದಲ್ಲಿ ಪುರುಷೋತ್ತಮ ಎಂದು ಕರೆದಿರುವುದು ನನ್ನನ್ನು” ಎಂದು. ಇಲ್ಲಿ\nಲೋಕ ಎಂದರೆ ಪೌರುಷೇಯವಾದ ಪುರಾಣ ಗ್ರಂಥಗಳು. ಉದಾಹರಣೆಗೆ: ರಾಮಾಯಣ, ಮಹಾಭಾರತ,\nಪಂಚರಾತ್ರ, ಪುರಾಣ, ಇತ್ಯಾದಿ. ಹೀಗೆ “ಪುರುಷೋತ್ತಮ” ಎನ್ನು ವುದು ಪರಮ ಮುಖ್ಯವಾಗಿ ಕೇವಲ\nಭಗವಂತನಿಗೆ ಮಾತ್ರ ಅನ್ವಯ.\n",
  "15.19": "ಯಃ ಮಾಮ್‌ ಏವಮ್‌ ಅಸಮ್ಮೂಢಃ ಜಾನಾತಿ ಪುರುಷೋತ್ತಮಮ್‌ ।\nಸಃ ಸರ್ವವಿತ್‌ ಭಜತಿ ಮಾಮ್‌ ಸರ್ವಭಾವೇನ ಭಾರತ -ಭ್ರಾಂತಿಯಳಿದು, ಹೀಗೆ ನನ್ನ ನ್ನು\nಪುರುಷೋತ್ತಮನೆಂದು ತಿಳಿದವನು ಎಲ್ಲವನ್ನೂ ತಿಳಿದವನು. ಓ ಭಾರತಾ, ಎಲ್ಲಾ ಬಗೆಯಿಂದಲೂ ಅವನು\n\nನನ್ನನ್ನೇ ಆರಾಧಿಸುತ್ತಾನೆ.\n\nಇಲ್ಲಿ ಹೇಳಿರುವ ವಿಚಾರಗಳನ್ನು ತಿಳಿದು ನಮಗೇನು ಲಾಭ ಎಂದು ಪ್ರಶ್ನೆ ಮಾಡುವವರಿಗೆ ಕೃಷ್ಣನ ಉತ್ತರ ಈ\nಶ್ಲೋಕದಲ್ಲಿದೆ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ನನ್ನನ್ನು ಪುರುಷೋತ್ತಮ ಎಂದು ಅಹಂಕಾರವಿಲ್ಲದೆ, ಸ್ವಚ್ಛವಾದ\nಮನಸ್ಸಿನಿಂದ, ಕೋಪವನ್ನು ಗೆದ್ದು, ಮೋಹವಳಿದು ತಿಳಿದವನು- ಎಲ್ಲವನ್ನೂ ತಿಳಿದವನು” ಎಂದು. ನಮಗೆ\n\nಭಗವಂತನ ಅಸ್ತಿತ್ವ ಅರ್ಥವಾಗಬೇಕಾದರೆ ಮೊದಲು ಜಡಕ್ಕಿಂತ ಭಿನ್ನವಾದ “ನಾನು' ಎನ್ನುವ ಚೇತನ ಈ\nದೇಹದಲ್ಲಿದೆ. ಎಂದು ಅರ್ಥವಾಗಬೇಕು (by awareness of self). ಹೀಗೆ ಆತ್ಮಸಾಕ್ಷಾತ್ಕಾರವಾದ ಮೇಲೆ,\nಭಗವಂತನ ಬಿಂಬ ಸಾಕ್ಷಾತ್ಕಾರವಾಗುತ್ತದೆ. ಯಾರು ಭಗವಂತನನ್ನು ತಿಳಿಯುತ್ತಾನೋ, ಅವನು ಎಲ್ಲವನ್ನೂ\nತಿಳಿಯಬಲ್ಲ. ಹೀಗಾಗಿ ನಾವು ಪ್ರಾಣಿಗಳಿಗಿಂತ ಬಿನ್ನವಾಗಿ ಜ್ಞಾನಿಗಳಾಗಿ ಬದುಕಬೇಕು. ಹೀಗೆ ಬದುಕಿದಾಗ\nನಮಗೆ ದೇವರ ಮೇಲಿನ ಅಚಲ ಭಕ್ತಿ ಗಟ್ಟಿಗೊಳ್ಳುತ್ತದೆ. ಜ್ಞಾನಿ ಎನಿಸಿದವ ತನ್ನ ಸರ್ವಸ್ವವನ್ನು\nಕಳೆದುಕೊಂಡರೂ ಕೂಡಾ, “ಅದು ಭಗವಂತನ ಕರುಣೆ' ಎಂದು ಸ್ವೀಕರಿಸುತ್ತಾನೆ. ಅಜ್ಞಾನಿಯಲ್ಲಿ ಈ ದೃಢ ಭಕ್ತಿ\nಇರದು. ಈ ರೀತಿ ದೃಢಭಕ್ತಿ ಮೂಡಬೇಕಾದರೆ ನಾವು 'ಭಾರತ'ರಾಗಬೇಕು. ನಿರಂತರ ಜ್ಞಾನ ತೃಷೆ, ಜ್ಞಾನಿಗಳಲ್ಲಿ\nಭಕ್ತಿ, ಭಗವದ್‌ ಭಕ್ತರಲ್ಲೇ ಹಿರಿಯರಾದ ಪ್ರಾಣದೇವರಲ್ಲಿ ಭಕ್ತಿ- ನಮ್ಮನ್ನು ಭಾರತರನ್ನಾಗಿ ಮಾಡಬಲ್ಲದು.",
  "15.20": "ಇತಿ ಗುಹ್ಯತಮಮ್‌ ಶಾಸ್ತ್ರಮ್‌ ಇದಮ್‌ ಉಕ್ತಮ್‌ ಮಯಾ ಅನಘ |\n\nಏತತ್‌ ಬುದ್ಧ್ವಾ ಬುದ್ಧಿಮಾನ್‌ ಸ್ಯಾತ್‌ ಕೃತಕೃತ್ಯಶ್ಚ ಭಾರತ--ಓ ಅನಘ, ತುಂಬಾ ಮುಚ್ಚಿಡಬೇಕಾದ ಮಾತನ್ನು\nನಾನು ನಿನ್ನೆದುರು ಬಿಚ್ಚಿಟ್ಟಿದ್ದೇನೆ. ಇದನ್ನರಿತವನು ಭಗವಂತನನ್ನು ಬಲ್ಲವನಾಗುತ್ತಾನೆ. ಅವನು ಮತ್ತೆ\nಮಾಡಬೇಕಾದ್ದೇನೂ ಉಳಿಯುವುದಿಲ್ಲ.\n\nಇದು ಅಧ್ಯಾತ್ಮ ಜಿಜ್ಞಾಸುಗಳಿಗೆ ಹೇಳಬೇಕಾದ ರಹಸ್ಯಗಳಲ್ಲೇ ಸರ್ವಶ್ರೇಷ್ಠ ರಹಸ್ಯ. ಅಧ್ಯಾತ್ಮವನ್ನು ಆಸಕ್ತಿ\nಉಳ್ಳವರಿಗೆ ಅವರ ಆಸಕ್ತಿಯ ಆಳವನ್ನು ತಿಳಿದು ಹೇಳಬೇಕು. ಶಾಸ್ತ್ರದ ಪ್ರಮೇಯವನ್ನು ಎಂದೂ ಬೀದಿಯಲ್ಲಿ\nತೆರೆದಿಡಬಾರದು. ಏಕೆಂದರೆ ಅದು ವ್ಯರ್ಥವಾಗಬಾರದು ಮತ್ತು ಅನರ್ಥವಾಗಲೂಬಾರದು. ಯಾರಿಗೆ ಗ್ರಹಣ\nಮಾಡುವ ಯೋಗ್ಯತೆ ಇದೆ, ಆಸಕ್ತಿ, ಶ್ರದ್ಧೆ, ಭಕ್ತಿ ಇದೆ, ಅವರಿಗೆ ಮಾತ್ರ ಹೇಳಬೇಕು. ಇದು ರಹಸ್ಯಗಳಲ್ಲೇ\nಅತ್ಯಂತ ಗೋಪ್ಯವಾದುದು. ಕ್ಷರಪುರುಷರ ಜ್ಞಾನ, ಅಕ್ಷರಪುರುಷಳ ಜ್ಞಾನ ಮತ್ತು ಪುರುಷೋತ್ತಮನ ಜ್ಞಾನವನ್ನು\nತಿಳಿದವನು ಶಾಸ್ತ್ರವನ್ನು ಬಲ್ಲವನು. ಶಾಸ್ತ್ರ ಎಂದರೆ ತಿಳಿದವರು ತಿಳಿಯದವರಿಗೆ ತಿಳಿಹೇಳಬೇಕಾದ ವಸ್ತು.\n“ಬಹಳ ರಹಸ್ಯವಾಗಿ, ಜೋಪಾನವಾಗಿ ಕಾಪಾಡಬೇಕಾದ ಉಪದೇಶಾರ್ಹ ವಿಷಯವಿದು. ಇದಕ್ಕಿಂತ\nಶ್ರೇಷ್ಠವಾದ ಉಪದೇಶ ಇನ್ನೊಂದಿಲ್ಲ. ಅಂತಹ ಗೋಪ್ಯವಾದ ವಿಷಯವನ್ನು ನಿನಗೆ ಹೇಳಿದೆ-ಏಕೆಂದರೆ ನೀನು\n\"ಅನಘ' ಅದಕ್ಕಾಗಿ?” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. \"ಅನಘ' ಎಂದರೆ ಯಾವ ದೋಷವೂ ಇಲ್ಲದವ. ನಾವು ಜ್ಞಾನಕ್ಕೆ\nಭಾದಕವಾಗಿರುವ ದುರಿತಗಳಿಂದ, ದೋಷಗಳಿಂದ ಮೊದಲು ಮುಕ್ತರಾಗಬೇಕು. ನಮ್ಮ ಮನಸ್ಸು ಕೆಟ್ಟ\nವಿಚಾರದಿಂದ ಕಲುಪಿತವಾದರೆ. ಆಗ ನಮಗೆ ಗೀತೆ ಅರ್ಥವಾಗುವುದಿಲ್ಲ. ಯಾವುದೇ ಪೂರ್ವಾಗ್ರಹ\nಆವೇಶಗಳಿಲ್ಲದೆ ಪೂರ್ಣ ಭಗವಂತನಲ್ಲಿ ಶರಣಾದಾಗ ಮನಸ್ಸು ಪಾಪ ರಹಿತವಾಗಬಲ್ಲದು.\n\nಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ಇದು ಎಲ್ಲಾ ತಿಳುವಳಿಕೆಗಳ ಬೇರು. ಇದನ್ನು ತಿಳಿದವನು ಕೃತಕೃತ್ಯ” ಎಂದು. ಜೀವನದಲ್ಲಿ\n\nಭಗವಂತನನ್ನು ತಿಳಿದವನು. ಸಾರ್ಥಕವಾದ ಬದುಕನ್ನು ಬದುಕಬಲ್ಲ. ಭಗವಂತನ ಅರಿವಿನೊಂದಿಗೆ\nಬದುಕುವುದೇ ಜೀವನದ ಸಾರ್ಥಕ್ಯ.\n\nಇತಿ ಪಂಚದಶೋ*ಧ್ಯಾಯಃ\nಹದಿನೈದನೆಯ ಅಧ್ಯಾಯ ಮುಗಿಯಿತು\n\nಅಧ್ಯಾಯ ಹದಿನಾರು\n\nಹಿಂದಿನ ಅಧ್ಯಾಯದ ಕೊನೆಯಲ್ಲಿ ನಾವು 'ಅನಘ'ರಾಗಬೇಕು, 'ಭಾರತ'ರಾಗಬೇಕು-ಎನ್ನುವ ಸಂದೇಶವನ್ನು\nಕೊಟ್ಟ ಕೃಷ್ಣ, ಈ ಅಧ್ಯಾಯದಲ್ಲಿ ಭಗವಂತನ ಸಾಧನೆ ಮಾಡುವವರಲ್ಲಿ ಇರಬೇಕಾದ ಗುಣಗಳ ಬಗ್ಗೆ\nವಿವರಿಸುತ್ತಾನೆ. ಇಲ್ಲಿ ಕೃಷ್ಣ 'ದೈವೀಸ್ವಭಾವ' ಮತ್ತು 'ಆಸುರೀಸ್ವಭಾವ' ಹಾಗೂ ಅದರ ಗುಣಲಕ್ಷಣಗಳನ್ನು\nಸ್ಪಷ್ಟವಾಗಿ ನಮ್ಮ ಮುಂದೆ ತೆರೆದಿಟ್ಟಿದ್ದಾನೆ. ದೈವೀಸ್ವಭಾವ ಎಂದರೆ ದೇವತೆಗಳ ಸ್ವಭಾವ-ಇದು ಜ್ಞಾನ ಸಾಧನ.\nಆಸುರೀಸ್ವಭಾವ ಎಂದರೆ ಅಸುರರ ಸ್ವಭಾವ-ಅದು ಜ್ಞಾನ ವಿರೋಧಿ. ದೈವೀ ಸ್ವಭಾವವನ್ನು ನಾವು ನಮ್ಮ\nಜೀವನದಲ್ಲಿ ಅಳವಡಿಸಿಕೊಂಡರೆ ಜ್ಞಾನ ಸಾಧನೆ ಸಾಧ್ಯ. ಅದನ್ನು ಬಿಟ್ಟು ಆಸುರ ಸ್ವಭಾವವನ್ನು\nಅಳವಡಿಸಿಕೊಂಡರೆ. ಅದು. ನಮ್ಮನ್ನು ಅಜ್ಞಾನದ ದಾರಿಯಲ್ಲಿ ಕೊಂಡೊಯ್ಯುತ್ತದೆ. ಒಂದು ಬೆಳಕಿನ\nದಾರಿಯಾದರೆ ಇನ್ನೊಂದು ಕತ್ತಲಿನ ದಾರಿ. ಯಾವ ದಾರಿಯಲ್ಲಿ ನಡೆಯಬೇಕು ಎನ್ನುವ ತೀರ್ಮಾನ ನಮಗೆ\nಬಿಟ್ಟಿದ್ದು. ನಮಗೆ ಬೆಳಕಿನ ದಾರಿ ಬೇಕಿದ್ದರೆ, ಆ ದಾರಿಯಲ್ಲಿ ಸಾಗಲು ಬೇಕಾದ ನಡೆಯನ್ನು ಈ ಅಧ್ಯಾಯ\nತಿಳಿಸುತ್ತದೆ. ಅದೇ ರೀತಿ ಕತ್ತಲೆಯ ದಾರಿಯಲ್ಲಿ ಸಾಗುವವರ ಬುದ್ಧಿ ಹೇಗಿರುತ್ತದೆ ಎನ್ನುವುದನ್ನೂ ಇಲ್ಲಿ\nವಿವರಿಸಲಾಗಿದೆ. ಇಲ್ಲಿ ದೈವೀ ಮತ್ತು ಆಸುರೀ ಸ್ವಭಾವವನ್ನು ಬಿಟ್ಟು ಬೇರೆಯಾಗಿ ಮಾನವ ಸ್ವಭಾವವನ್ನು\nವಿವರಿಸಿಲ್ಲ... ಏಕೆಂದರೆ ಮಾನವ ಸ್ವಭಾವ ಈ ಎರಡೂ ಸ್ವಭಾವದ ಮಿಶ್ರಣ. ಈ ಮಿಶ್ರಣದಲ್ಲಿನ\nಪ್ರಮಾಣಭೇದದಿಂದ ಮಾನವರಲ್ಲಿ ವೈವಿಧ್ಯತೆ ಬರುತ್ತದೆ. ಒಟ್ಟಿನಲ್ಲಿ ಇರುವುದು ಎರಡೇ ದಾರಿ. ಬೆಳಕಿನ ದಾರಿ\nನಮ್ಮನ್ನು ಭಗವಂತನೆಡೆಗೆ ಕೊಂಡೊಯ್ಯುತ್ತದೆ; ಕತ್ತಲಿನ ದಾರಿ ನಾವು ಭಗವಂತನಿಗೆ ಬೆನ್ನುಹಾಕಿ\nನಡೆಯುವಂತೆ ಮಾಡುತ್ತದೆ.\n\nಭಗವಂತನೆಡೆಗೆ ಹೋಗುವವರಲ್ಲಿ ಇರಬೇಕಾದ ಒಳ್ಳೆಯ ಲಕ್ಷಣಗಳ ಬಗ್ಗೆ ಹೇಳುತ್ತಾ ಈ ಅಧ್ಯಾಯ\nಪ್ರಾರಂಭವಾಗುತ್ತದೆ. ಅಧ್ಯಾತ್ಮದಲ್ಲಿ ಖಂಡಿತವಾಗಿ ಬೇಕಾದ, ನಾವು ರೂಢಿಸಿಕೊಳ್ಳಬೇಕಾದ ಪ್ರಮುಖ\nಇಪ್ಪತ್ತಾರು ಗುಣಗಳನ್ನು ಕೃಷ್ಣ ಈ ಅಧ್ಯಾಯದ ಮೊದಲ ಮೂರು ಶ್ಲೋಕದಲ್ಲಿ ವಿವರಿಸಿದ್ದಾನೆ. ಬನ್ನಿ,\nಭಗವಂತನತ್ತ ನಮ್ಮನ್ನು ಕೊಂಡೊಯ್ಯುವ ಬೆಳಕಿನ ದಾರಿಯ ಗುಣ ಲಕ್ಷಣಗಳನ್ನು ಕೃಷ್ಣನಿಂದ ತಿಳಿದು,\nಕತ್ತಲಿನಿಂದ ಬೆಳಕಿನತ್ತ ಹೆಜ್ಜೆ ಹಾಕೋಣ.\n\nಭಗವಾನುವಾಚ ।\nಅಭಯಂ ಸತ್ತ್ವಸಂಶುದ್ಧಿರ್ಜಾನಯೋಗವ್ಯವಸ್ಥಿತಿಃ |\nದಾನಂ ದಮಶ್ಚ ಯಜ್ಞಶ್ಚ ಸ್ವಾಧ್ಯಾಯಸ್ತಪ ಆರ್ಜವಮ್‌ ॥೧॥\n\nಅಹಿಂಸಾ ಸತ್ಯಮಕ್ರೋಧಸ್ಯಾಗಃ ಶಾನ್ರಿರಪೈಶುನಮ್‌ |\nದಯಾ ಭೂತೇಷ್ಟಲೋಲುತ್ವಂಮಾರ್ದವಂ ಹ್ರೀರಚಾಪಲಮ್‌ ॥೨॥\n\nತೇಜಃ ಕ್ಷಮಾ ಧೃತಿಃ ಶೌಚಮದ್ರೋಹೋ ನಾತಿಮಾನಿತಾ |\nಭವಂತಿ ಸಂಪದಂ ದೈವೀಮಭಿಜಾತಸ್ಯ ಭಾರತ ॥೩॥\n\nಭಗವಾನ್‌ ಉವಾಚ-ಭಗವಂತ ಹೇಳಿದನು:\n\nಅಭಯಂ ಸತ್ತ್ವಸಂಶುದ್ಗಿಃ ಜ್ಞಾನಯೋಗ ವ್ಯವಸ್ಥಿತಿ: |\n\nದಾನಮ್‌ ದಮಃ ಚ ಯಜ್ಞಚ ಸ್ವಾಧ್ಯಾಯಃ ತಪಃ ಆರ್ಜವಮ್‌ |\n\nಅಹಿಂಸಾ ಸತ್ಯಮ್‌ ಅಕ್ರೋಧಃ ತ್ಯಾಗಃ ಶಾಂತಿಃ ಅಪೈಶುನಮ್‌ |\n\nದಯಾ ಭೂತೇಷು ಅಲೋಲುತ್ವಂ ಮಾರ್ದವಂ ಶ್ರೀಃ ಅಚಾಪಲಮ್‌ ॥\n\nತೇಜಃ ಕ್ಷಮಾ ಧೃತಿಃ ಶೌಚಮ್‌ ಅದ್ರೋಹಃ ನ ಅತಿಮಾನಿತಾ |\n\nಭವಂತಿ ಸಂಪದಂ ದೈವೀಮ್‌ ಅಭಿಜಾತಸ್ಯ ಭಾರತ -ಹೇ ಭಾರತಾ, ದೈವೀಸಂಪತ್ತು [ಒಳ್ಳೆಯ ನಡತೆ]\nಹೊತ್ತು ಹುಟ್ಟಿದವನಲ್ಲಿ ಈ ಗುಣಗಳಿರುತ್ತವೆ: ಅಂಜದಿರುವುದು ಮತ್ತು ಅಂಜಿಸದಿರುವುದು, ತಿಳಿಯಾದ ಮನಸ್ಸು,\nಅರಿವಿನ ದಾರಿಯಲ್ಲಿ",
  "16.1": "ಅಹಿಂಸಾ ಸತ್ಯಮಕ್ರೋಧಸ್ಯಾಗಃ ಶಾನ್ರಿರಪೈಶುನಮ್‌ |\nದಯಾ ಭೂತೇಷ್ಟಲೋಲುತ್ವಂಮಾರ್ದವಂ ಹ್ರೀರಚಾಪಲಮ್‌",
  "16.2": "ತೇಜಃ ಕ್ಷಮಾ ಧೃತಿಃ ಶೌಚಮದ್ರೋಹೋ ನಾತಿಮಾನಿತಾ |\nಭವಂತಿ ಸಂಪದಂ ದೈವೀಮಭಿಜಾತಸ್ಯ ಭಾರತ",
  "16.3": "ಭಗವಾನ್‌ ಉವಾಚ-ಭಗವಂತ ಹೇಳಿದನು:\n\nಅಭಯಂ ಸತ್ತ್ವಸಂಶುದ್ಗಿಃ ಜ್ಞಾನಯೋಗ ವ್ಯವಸ್ಥಿತಿ: |\n\nದಾನಮ್‌ ದಮಃ ಚ ಯಜ್ಞಚ ಸ್ವಾಧ್ಯಾಯಃ ತಪಃ ಆರ್ಜವಮ್‌ |\n\nಅಹಿಂಸಾ ಸತ್ಯಮ್‌ ಅಕ್ರೋಧಃ ತ್ಯಾಗಃ ಶಾಂತಿಃ ಅಪೈಶುನಮ್‌ |\n\nದಯಾ ಭೂತೇಷು ಅಲೋಲುತ್ವಂ ಮಾರ್ದವಂ ಶ್ರೀಃ ಅಚಾಪಲಮ್‌ ॥\n\nತೇಜಃ ಕ್ಷಮಾ ಧೃತಿಃ ಶೌಚಮ್‌ ಅದ್ರೋಹಃ ನ ಅತಿಮಾನಿತಾ |\n\nಭವಂತಿ ಸಂಪದಂ ದೈವೀಮ್‌ ಅಭಿಜಾತಸ್ಯ ಭಾರತ -ಹೇ ಭಾರತಾ, ದೈವೀಸಂಪತ್ತು [ಒಳ್ಳೆಯ ನಡತೆ]\nಹೊತ್ತು ಹುಟ್ಟಿದವನಲ್ಲಿ ಈ ಗುಣಗಳಿರುತ್ತವೆ: ಅಂಜದಿರುವುದು ಮತ್ತು ಅಂಜಿಸದಿರುವುದು, ತಿಳಿಯಾದ ಮನಸ್ಸು,\nಅರಿವಿನ ದಾರಿಯಲ್ಲಿ ನೆಲೆಗೊಳ್ಳುವುದು, ಕೊಡುಗೈತನ, ಇಂದ್ರಿಯಗಳ ಮೇಲೆ ಹಿಡಿತ, ದೇವತೆಗಳ ಆರಾಧನೆ,\nವೇದಗಳ ಅಧ್ಯಯನ, ನೋಂಪಿಯ ನಿಷ್ಠೆ, ನೇರತನ, ನೋಯಿಸದಿರುವುದು, ನಿಜ ನುಡಿಯುವುದು,\nಪಿಡುಕದಿರುವುದು, ಧಾರಾಳತನ, ಭಗವಂತನಲ್ಲಿ ಬಗೆ ನೆಟ್ಟಿರುವುದು, ಚಾಡಿ ಹೇಳದಿರುವುದು, ಪ್ರಾಣಿಗಳಲ್ಲಿ\nಕನಿಕರ, ಅತಿಯಾಸೆ ಇರದಿರುವುದು, ನಮ್ರತೆ, ನಾಚಿಕೆ, ಗಟ್ಟಿತನ, ಕುಗ್ಗದಿರುವುದು, ತಪ್ಪನ್ನು ಮನ್ನಿಸುವ ತಾಳ್ಮೆ,\nಕೆಚ್ಚು, ಳಹೊರಗಣ ಮಡಿ, ಎರಡೆಣಿಸದಿರುವುದು, ಮತ್ತು ಬೀಗದಿರುವುದು.\n\nಅಧ್ಯಾತ್ಮದ ಸಾಧನೆಯಲ್ಲಿರಬೇಕಾದ ಇಪ್ಪತ್ತಾರು ಸದ್ಗುಣಗಳನ್ನು ಕೃಷ್ಣ ಇಲ್ಲಿ ವಿವರಿಸಿದ್ದಾನೆ. ಈ ಇಪ್ಪತ್ತಾರು\nಗುಣಗಳ ಬೆನ್ನುಹತ್ತಿ ಅದರಲ್ಲಿ ನಮ್ಮಲ್ಲಿರುವ ಗುಣವನ್ನು ನಾವು ಗುರುತಿಸಿಕೊಂಡು, ಅದನ್ನು ನಾವು\nವೃದ್ಧಿಪಡಿಸಿಕೊಳ್ಳಬೇಕು ಮತ್ತು ಇಲ್ಲದ ಗುಣವನ್ನು ಬೆಳೆಸಿಕೊಳ್ಳಬೇಕು.\n(೧) ಅಭಯಂ (ನಿರ್ಭಯತ್ವ): ಇದು ಅಧ್ಯಾತ್ಮದ ದಾರಿಯಲ್ಲಿ ಸಾಗುವವರಿಗಿರಬೇಕಾದ ಮೊತ್ತ\nಮೊದಲ ಗುಣ. ಅಧ್ಯಾತ್ಮ ಹೇಡಿಗಳಿಗೆ ಹೇಳಿಸಿದ್ದಲ್ಲ. ಹನುಮಂತನ ಕುರಿತಾದ ಈ ಕೆಳಗಿನ ಶ್ಲೋಕ\nಹೇಳುವಂತೆ:\n\nಬುದ್ಧಿರ್ಬಲಂ ಯಶೋ ಧೈರ್ಯಂ ನಿರ್ಭಯತ್ವಂ ಅರೋಗತಾ |\n\nಅಜಾಡ್ಯಂ ವಾಕ್‌ ಪಟುತ್ವಂ ಚ ಹನುಮತ್‌ ಸ್ಮರಣಾತ್‌ ಭವೇತ್‌ ॥\n\nನಮ್ಮಲ್ಲಿ ನಿರ್ಭಯತ್ವ ಬರಬೇಕಾದರೆ ಸಾವು ಪ್ರಾಣದೇವರ ಉಪಾಸನೆ ಮಾಡಬೇಕು. ಧೈರ್ಯವಿಲ್ಲದೆ\nವೇದಾಂತ ಓದಿದರೆ ದೃಢನಂಬಿಕೆಬರುವುದಿಲ್ಲ. ನಾವು ಉಪಾಸನೆ ಮಾಡುವಾಗ ಯಾರೋ\nಬಂದು ಏನೋ ಹೇಳುತ್ತಾರೆ. ಆಗ ನಮ್ಮ ಮನಸ್ಸು ದೃಢವಾಗಿ ದೇವರಲ್ಲಿ ನಿಲ್ಲುವುದಿಲ್ಲ. ಯಾರು ಏನೇ ಹೇಳಲಿ,\n“ನಾನು ಹಿಡಿದ ದಾರಿಯನ್ನು ಬಿಡುವುದಿಲ್ಲ, ದೇವರು ನನ್ನನ್ನು ರಕ್ಷಿಸುತ್ತಾನೆ' ಎನ್ನುವ ದೃಢ ನಂಬಿಕೆ ಇದ್ದಾಗ\nಮಾತ್ರ ನಾವು ಯಶಸ್ಸನ್ನು ಕಾಣಲು ಸಾಧ್ಯ.\n\nಇಂದಿನ ದಿನಗಳಲ್ಲಿ “ಹೀಗೆ ಮಾಡಿದರೆ ಅನರ್ಥ, ಹಾಗೆ ಮಾಡಿದರೆ ಅನರ್ಥ” ಎಂದು ಹೆದರಿಸುವ ಜನರೇ ಹೆಚ್ಚು.\nಹೀಗೆ ಹೇಳುವ ಮಂದಿಗೆ ಶಾಸ್ತ್ರದ ಗಂಧ-ಗಾಳಿಯೂ ಗೊತ್ತಿರುವುದಿಲ್ಲ. ಇವರು ಹಿರಣ್ಯಕಶಿಪುವಿನ ಆವೇಶವುಳ್ಳ\n\nಜನ. ಉದಾಹರಣೆಗೆ ಕೆಲವರು “ವಿಷ್ಣುಸಹಸ್ರನಾಮವನ್ನು ಹೆಂಗಸರು ಹೇಳಬಾರದು' ಎಂದು ಹೆದರಿಸುತ್ತಾರೆ.\nಆದರೆ ವಿಪರ್ಯಾಸವೆಂದರೆ ದೇವರ ನಾಮವಿರುವುದೇ ನಮ್ಮ ಅಭಯಕ್ಕಾಗಿ. ಇದನ್ನು ತಿಳಿಯದೆ ಭಯಬಿದ್ದು\nದೂರ ಸರಿದರೆ ಅದರಿಂದ ನಮಗೇ ನಷ್ಟ. ದೇವರು ಎಂದೂ ಭಯಾನಕ ಅಲ್ಲ. ಆತ ಭಯಾನಕನಾಗುವುದು\nಕೇವಲ ಹಿರಣ್ಯಕಶಿಪುವಿನ ಆವೇಶವುಳ್ಳವರಿಗೇ ಹೊರತು ಪ್ರಹ್ಲಾದನ ಆವೇಶವುಳ್ಳವರಿಗಲ್ಲ. ನಾವು\nಪ್ರಹ್ಲಾದನಂತಾಗಿ, ನಮ್ಮನ್ನು ಹೆದರಿಸುವ ಹಿರಣ್ಯಕಶಿಪುಗಳಿಗೆ ಭಯಬೀಳದೆ, ಅಭಯಪ್ರದ ಭಗವಂತನನ್ನು\nಸ್ತುತಿಸಬೇಕು.\n\nಅಧ್ಯಾತ್ಮ ಸಾಧಕ ಎಂದೂ ಹೇಡಿಯಾಗಿರುವುದಿಲ್ಲ. ಏಕೆಂದರೆ ಅವನಿಗೆ ಒಂದು ವಿಷಯ ಖಚಿತವಾಗಿ\nತಿಳಿದಿರುತ್ತದೆ. “ನಾನು ಹೆದರುವುದಕ್ಕೆ ಅರ್ಥವಿಲ್ಲ, ಏಕೆಂದರೆ ಭಗವಂತ ರಕ್ಷಿಸುವ ತನಕ ನನ್ನನ್ನು ಇಡೀ\nಪ್ರಪಂಚ ಏನೂ ಮಾಡಲಾರದು; ಭಗವಂತ ಕೈಬಿಟ್ಟಮೇಲೆ ಯಾರೂ ನನ್ನನ್ನು ರಕ್ಷಿಸಲಾರರು”. ಈ ರೀತಿ\nನಿಶ್ಚಿತಾಭಿಪ್ರಾಯ ನಮ್ಮಲ್ಲಿ ಬೆಳೆಯಬೇಕು.\n\n“ರಕ್ಷತೀತ್ಯೇವ ವಿಶ್ವಾಸಃ”-ಭಗವಂತ ತನ್ನ ಭಕ್ತರನ್ನು ಎಂದೂ ಬಿಟ್ಟು ಕೊಡುವುದಿಲ್ಲ. ಆದ್ದರಿಂದ \"'ಅಭಯ'\nನಮ್ಮಲ್ಲಿರಬೇಕಾದ ಮೊದಲ ಅರ್ಹತೆ. ಈ ವಿಶ್ವಾಸ ನಮ್ಮಲ್ಲಿ ಎಷ್ಟು ದೃಢವಾಗುವುದೋ ಅಷ್ಟು ರಕ್ಷಣೆ\nಭಗವಂತನಿಂದ ಭಕ್ತನಿಗೆ ದೊರೆಯುತ್ತದೆ.\n\n(೨) ಸತ್ತ್ವಸಂಶುದ್ಧಿ : ನಮ್ಮ ಮನಃಶುದ್ಧಿ ಅಧ್ಯಾತ್ಮ ಸಾಧನೆಯಲ್ಲಿ ಬಹಳ\nಮುಖ್ಯ. ಸಾಮಾನ್ಯವಾಗಿ ನಮ್ಮ ಮನಸ್ಸು ಅನುವಂಶೀಯ ಕಾರಣದಿಂದ, ಅಥವಾ ಪರಿಸರದ ಪ್ರಭಾವದಿಂದ\nಶುದ್ಧವಾಗಿರುವುದಿಲ್ಲ. ಹದಿಮೂರನೇ ಶತಮಾನದಲ್ಲೇ ಆಚಾರ್ಯರು “ದೌರ್ಲಭ್ಯಾತ್‌ ಶುದ್ಧ ಬುದ್ಧೀನಾಂ”\nಎಂದಿರುವುದನ್ನು ನಾವು ಇಲ್ಲಿ ಗಮನಿಸಬೇಕು. ಶುದ್ಧ ಮನಸ್ಸಿರುವವರು ಸಮಾಜದಲ್ಲಿ ತುಂಬಾ ದುರ್ಲಭ.\n\nಇಲ್ಲಿ ಕೃಷ್ಣ ಕೇವಲ ಸತ್ತ್ವ ಶುದ್ಧಿ ಎಂದು ಹೇಳದೆ, \"ಸತ್ತ್ವ ಸಂ-ಶುದ್ಧಿ' ಎಂದು ಹೇಳಿದ್ದಾನೆ. ನಮ್ಮ ಮನಸ್ಸು\nಒಮ್ಮೊಮ್ಮೆ ಶುದ್ಧವಾಗಿರುತ್ತದೆ, ನಿದ್ದೆಯಲ್ಲಿ ಎಲ್ಲರ ಮನಸ್ಸೂ ಶುದ್ಧ. ಆದರೆ ಇಲ್ಲಿ ಕೃಷ್ಣ ಹೇಳುವುದು ಸದಾ\nಶುದ್ಧವಾಗಿರುವ ಎಚ್ಚರದ ಮನಸ್ಸು. ಇದನ್ನು ಭಾಗವತದಲ್ಲಿ “ಸತ್ತ್ವಂ ವಿಶುದ್ಧಂ ವಸುದೇವಶಬ್ದಿತಂ”..(೪-೩೦-\n೨೩) ಎಂದಿದ್ದಾರೆ. ಅಂದರೆ “ಸದಾ ಶುದ್ಧವಾಗಿರುವ ಮನಸ್ಸಿಗೆ ವಾಸುದೇವ ಗೋಚರನಾಗುತ್ತಾನೆ” ಎಂದರ್ಥ.\nಆದ್ದರಿಂದ ಅಧ್ಯಾತ್ಮ ಸಾಧನೆಗೆ ಯಾವುದೇ ಕೊಳೆ ಇಲ್ಲದ, ಯಾವುದೇ ಪೂರ್ವಾಗ್ರಹ ಇಲ್ಲದ ಮನಸ್ಸು ಬಹಳ\nಮುಖ್ಯ.\n(೩) ಜ್ಞಾನಯೋಗ ವ್ಯವಸ್ಥಿತಿಃ (ನಿರಂತರ ಜ್ಞಾನಯೋಗದಲ್ಲಿ ಮನಸ್ಸನ್ನು ನೆಲೆಗೊಳಿಸುವುದು):\nಉಪಾಸನಯೋಗ ಬಹಳ ಪ್ರಮುಖವಾದ ಯೋಗ. ಭಕ್ತಿ, ಜ್ಞಾನ ಮತ್ತು ಕರ್ಮಯೋಗ ಇದರ ಮೂರು\nಮುಖಗಳು. ಇವು ಒಂದನ್ನೊಂದು ಬಿಟ್ಟು ಇರಲಾರವು. ಜ್ಞಾನಯೋಗ ಅಂದರೆ ಭಗವಂತನ ಹಿರಿಮೆಯನ್ನು\nತಿಳಿದು, ಅವನ ಪೂಜಾರೂಪವಾಗಿ ಕರ್ಮವನ್ನು ಮಾಡಿ, ಅವನಲ್ಲಿ ಭಕ್ತಿ ಮಾಡುವುದು. 'ವ್ಯವಸ್ಥಿತಿಃ' ಅಂದರೆ\nಅಚಲವಾದ ಸ್ಥಿತಿ. ಭಗವಂತನ ವಿಷಯವಾಗಿ ಅಚಲವಾದ ಮನಸ್ಸನ್ನಿಟ್ಟು, ನಿರಂತರ ಭಗವಂತನ ಚಿಂತನೆಯಲ್ಲಿ\nಮನಸ್ಸನ್ನು ನೆಲೆಗೊಳಿಸುವುದು. ಇದರಿಂದ ಮನಸ್ಸು ಸ್ವಚ್ಛವಾಗುತ್ತದೆ.\n\n(೪) ದಾನಂ(ನಮ್ಮಲ್ಲಿರುವುದನ್ನು ಇನ್ನೊಬ್ಬರಿಗೆ ಕೊಡುವುದು): ನಮ್ಮಲ್ಲಿ ಇರುವ ವಸ್ತು ಇನ್ನೊಬ್ಬರಲ್ಲಿ ಇಲ್ಲದೇ\nಇದ್ದಾಗ, ಅವರಿಗೆ ಅದು ಬಹಳ ಅಗತ್ಯವಿದ್ದಾಗ, ಆ ವಸ್ತು ನಮಗೆ ಮುಂದೆ ಅಗತ್ಯಬೀಳಬಹುದಾದರೂ ಕೂಡಾ,\n\nಅದರ ಬಗ್ಗೆ ಯೋಚಿಸದೆ, ಅರ್ಪಣಾ ಭಾವದಿಂದ ಕೊಡುವುದು ದಾನ. ಇದನ್ನು ಬಿಟ್ಟು ಮನೆಯಲ್ಲಿ ಅಗತ್ಯವಿಲ್ಲದ\nವಸ್ತುವನ್ನು ಸಾಗಹಾಕುವುದಕ್ಕೋಸ್ಕರ ಕೊಡುವುದು, ಉತ್ತಮ ದರ್ಜೆಯನ್ನು ಒಳಗಿಟ್ಟು, ಕೀಳು ದರ್ಜೆಯನ್ನು\nಕೊಡುವುದು-ದಾನವಲ್ಲ. ಕೊಡುವಾಗ ಮನಸ್ಸಿನಲ್ಲಿ ನಮಗೆ ಕೊಡುವ ವಸ್ತುವಿನ ಮೇಲೆ ಯಾವ ಮಮಕಾರವೂ\nಇರಕೂಡಾದು; 'ಕೊಡುತ್ತಿದ್ದೇನೆ', ಕೊಟ್ಟೆ' ಎನ್ನು ವ ಅಹಂಕಾರ ಇರಕೂಡಾದು. ಪೂರ್ಣ ಅರ್ಪಣಾ ಭಾವದಿಂದ\nಕೊಡಬೇಕು. ಕೊಡುವ ವಸ್ತು ಜ್ಞಾನವಾಗಿರಬಹುದು, ಧಾನ್ಯವಾಗಿರಬಹುದು, ಅಭಯವಾಗಿರಬಹುದು\n(ಇನ್ನೊಬ್ಬರಿಗೆ ಧೈರ್ಯ ಕೊಡುವುದು), ಹೀಗೆ ಯಾವುದೇ ಕಾರ್ಯವಿರಬಹುದು. ಅಲ್ಲಿ ಕಾರ್ಯಕ್ಕಿಂತ\nಮುಖ್ಯವಾದುದು ಆ ಕಾರ್ಯದ ಹಿಂದಿನ ನಮ್ಮ ಭಾವನೆ (ಇನ್ನೂ ಹೆಚ್ಚಿನ ವಿವರಣೆಯನ್ನು ಅ-೧೦, ಶ್ಲೋ-\n೦೫ರಲ್ಲಿ ವಿವರಿಸಲಾಗಿದೆ).\n\n(೫) ದಮ (೬) ಯಜ್ಞ : ಇಲ್ಲಿ ಈ ಎರಡು ಕ್ರಿಯೆಯನ್ನು ಕೃಷ್ಣ 'ಚ'-ಕಾರ ಬಳಸಿ(ದಮಶ್ಚ, ಯಜ್ಞಶ್ಚ) ಹೇಳಿದ್ದಾನೆ.\nಇದು ಇತರ ಎಲ್ಲಾ ನಡತೆಗಳೊಂದಿಗೆ ಬಹಳ ಮುಖ್ಯ ನಡತೆ ಎಂದು ತೋರಿಸಲು ಇಲ್ಲಿ ಚ-ಕಾರ ಬಳಸಲಾಗಿದೆ.\n'ದಮ' ಅಂದರೆ ಕೆಟ್ಟದ್ದನ್ನು ಮಾಡುವುದನ್ನು ಬಿಡುವುದು; ನಮ್ಮ ಇಂದ್ರಿಯಗಳು ಕೆಟ್ಟದ್ದನ್ನು ಮಾಡದಂತೆ\nನಿಯಂತ್ರಿಸುವುದು. ಯಜ್ಞ ಅಂದರೆ ಮಾಡುವ ಎಲ್ಲಾ ಕೆಲಸವನ್ನು ಭಗವದರ್ಪಣೆಯಾಗಿ ಮಾಡುವುದು. ನಾವು ಈ\nಎರಡು ನಡತೆಯನ್ನು ನಿರಂತರ ನಮ್ಮ ಜೀವನದಲ್ಲಿ ಪಾಲಿಸಬೇಕು. ಈ ಎರಡು ನಡತೆ ಇಲ್ಲದೆ, ಇತರ\nನಡತೆಯನ್ನು ಸಾಧಿಸಲು ಸಾಧ್ಯವಿಲ್ಲ.\n\n(೭) ಸ್ವಾಧ್ಯಾಯಃ - ಮೂರು ತರದಲ್ಲಿ ಸ್ವಾಧ್ಯಾಯವಿದೆ. ಸ್ವತಂತ್ರನಾದ ಭಗವಂತನ ಬಗೆಗೆ ಇರತಕ್ಕಂತಹ\nಸಮಗ್ರ ವೇದಗಳ ಅಧ್ಯಯನ-ಸ್ವಾಧ್ಯಾಯ; ಇದು ಸಾಧ್ಯವಾಗದೇ ಇದ್ದರೆ ಅವರವರ ಶಾಖೆಯ(ಸ್ವಂ)\nವೇದಾಧ್ಯಯನ. ಇದನ್ನು ಕೂಡಾ ಸ್ವಾಧ್ಯಾಯ ಎನ್ನು ತ್ತಾರೆ. ಇನ್ನು ಮೂರನೆಯದು ನಾವು ಗುರುಗಳಿಂದ ಕೇಳಿದ\nಅಧ್ಯಾತ್ಮ ವಿಚಾರವನ್ನು ಮನನ ಮಾಡಿ, ಸ್ವಪ್ರವಚನ ಮಾಡಿಕೊಂಡು, ನಮ್ಮ ಆತ್ಮಕ್ಕೆ ಆ ವಿಚಾರ ತಿಳಿದ ಮೇಲೆ\nಇನ್ನೊ ಬ್ಬರಿಗೆ ಹೇಳುವುದು. ಆದರೆ ಇಂದು ಈ ಸ್ವಾಧ್ಯಾಯ ಕಣ್ಮರೆಯಾಗುತ್ತಿದೆ. ಪತಂಜಲಿ ಹೇಳುತ್ತಾನೆ:\n“ವೇದಂ ಅಧಿತ್ಯ ತ್ವರಿತ ವಕ್ತಾರೋ ಭವಂತಿ” ಎಂದು. ಇಂದು ವಿಧ್ಯಾರ್ಥಿ-ನಾಳೆ ಅಧ್ಯಾಪಕ(ವಕ್ತಾರ॥). ನಡುವೆ\nಸ್ವಾಧ್ಯಾಯ ಎನ್ನುವ ವಿಚಾರ ಇಂದು ಇಲ್ಲವಾಗಿದೆ. “ತ್ವರಿತ ಅಧಿತ್ಯ”- ಎಲ್ಲವೂ ತ್ವರಿತ!\n\n(೮) ತಪಃ : ಕೃಷ್ಣ ಇಲ್ಲಿ ಹೇಳುವ ತಪಃ ಹಿಂದೆ ಹೇಳಿದ ತಪಸ್ಸಲ್ಲ. ನಮ್ಮ ಮನಸ್ಸು ದಾರಿ ತಪ್ಪಿ ಹೋಗದಂತೆ\nನಿಯಂತ್ರಣ ಮಾಡುವುದು “ದಮ'; ಅದರಿಂದ ಶಾಸ್ತ್ರದ ನಿರಂತರ ಅಧ್ಯಾಯನ “ಸ್ವಾಧ್ಯಾಯ'. ಇವೆರಡರಲ್ಲಿ\nನಮಗೆ ತೊಂದರೆ ಕೊಡುವ ಎರಡು ಅಂಶಗಳಿವೆ. ಅವುಗಳೆಂದರೆ ನಾಲಿಗೆ ಚಪಲ ಮತ್ತು ಲೈಂಗಿಕ ಆಸಕ್ತಿ. ಇವು\nಅಧ್ಯಯನದ ಮೂಲ ಶತ್ರುಗಳು. ಇದನ್ನು ನಿಯಂತ್ರಿಸುವುದು ತಪಃ. ಇದಕ್ಕಾಗಿ ಹಿಂದೆ ಪುಣ್ಯಕ್ಷೇತ್ರಕ್ಕೆ ಹೋದಾಗ\nತಮ್ಮ ಯಾವುದೋ ಒಂದು ತಿನ್ನುವ ಚಪಲವನ್ನು ಅಲ್ಲಿ ಬಿಟ್ಟುಬರುತ್ತಿದ್ದರು. ಯಾವುದಾದರೊಂದು ನೆಪದಿಂದ\nತಮ್ಮ ಚಪಲವನ್ನು ಕಳಚಿಕೊಳ್ಳುವುದು ಇದರ ಹಿಂದಿನ ಕಾರಣ.\n\n(೯) ಅರ್ಜವಮ್‌ (ಪ್ರಾಮಾಣಿಕತೆ): ನೇರ ನಡೆ ನುಡಿ. ಮಾತನಾಡುವುದೊಂದು-\nಮಾಡುವುದು ಇನ್ನೊಂದು ಮಾಡದೇ, ಪ್ರಾಮಾಣಿಕತೆಯಿಂದಿರುವುದು.\n\n(೧೦) ಅಹಿಂಸಾ : ಈ ಬಗ್ಗೆ ಅಧ್ಯಾಯ ಹತ್ತರಲ್ಲಿ(ಶ್ಲೋಕ-೦೫) ಸ್ವಲ್ಪ ಮಟ್ಟಿಗೆ ವಿಶ್ಲೇಷಿಸಿದ್ದೇವೆ. ದ್ವೇಷದಿಂದ,\nಅಸಹನೆಯಿಂದ, ಅಸೂಯೆಯಿಂದ ಇನ್ನೊಬ್ಬರಿಗೆ ನೋವನ್ನುಂಟುಮಾಡುವುದು ಹಿಂಸೆ. ಆಹಾರಕ್ಕಾಗಿ\n\nಇನ್ನೊಂದು ಜೀವವನ್ನು ಅನಿವಾರ್ಯವಾಗಿ ಸಾಯಿಸುವುದು ಹಿಂಸೆ ಅಲ್ಲ(ಉದಾ: ವನಸ್ಪತಿಗಳ ಸೇವನೆ,\nಕ್ಷತ್ರಿಯರ ಮಾಂಸಭಕ್ಷಣೆ ಇತ್ಯಾದಿ); ನಡೆಯುವಾಗ, ಉಸಿರಾಡುವಾಗ, ತಿಳಿಯದೇ ಸೂಕ್ಷ್ಮ ಜೀವಿಗಳು ಸತ್ತರೆ\nಅದು ಹಿಂಸೆ ಅಲ್ಲ; ದೇಶವನ್ನು ಕಾಯುವ ಸೈನಿಕ ತನ್ನ ಧರ್ಮ ಪಾಲನೆಗಾಗಿ ಶತ್ರು ಸೈನಿಕನನ್ನು ಕೊಂದರೆ ಅದು\nಹಿಂಸೆ ಅಲ್ಲ; ಮುಂದೆ ನಡೆಯುವ ಮಹಾ ಹಿಂಸೆಯನ್ನು ತಡೆಯಲು ಅನಿವಾರ್ಯವಾಗಿ ನಡೆಯುವ ಯುದ್ಧ ಹಿಂಸೆ\nಅಲ್ಲ(ಉದಾ: ಮಹಾಭಾರತ ಯುದ್ಧ); ಸಾವಿರಾರು ಜನರನ್ನು ರಕ್ಷಿಸುವುದಕ್ಕೋಸ್ಕರ ಒಬ್ಬ ನನ್ನು ಕೊಲ್ಲುವುದು\nಹಿಂಸೆ ಅಲ್ಲ (ಉದಾ: ದಿನಕ್ಕೆ ಹತ್ತು ಸಾವಿರ ಸೈನಿಕರನ್ನು ಕೊಲ್ಲುವ ಪಣತೊಟ್ಟು ಹಗಲೂ ರಾತ್ರಿ ಹೋರಾಡುತ್ತಿದ್ದ\nದ್ರೋಣಾಚಾರ್ಯರನ್ನು ಕೃಷ್ಣ ಕೊಲ್ಲಿಸಿರುವುದು); ವೈದ್ಯರು ರೋಗಿಯನ್ನು ಬದುಕಿಸುವುದಕ್ಕೋಸ್ಕರ ಮಾಡುವ\nಕ್ರಿಯೆ ಹಿಂಸೆ ಅಲ್ಲ; ಹೀಗೆ ಒಟ್ಟಿ ನಲ್ಲಿ ದ್ವೇಷ, ಅಸಹನೆ, ಅಸೂಯೆ, ಸ್ವಾರ್ಥವಿಲ್ಲದೆ ನಡೆಯುವ ಅನಿವಾರ್ಯವಾದ\nಹಿಂಸೆ-ಅಹಿಂಸೆ ಎನಿಸುತ್ತದೆ.\n\nಇನ್ನೊಬ್ಬರಿಗೆ ತೊಂದರೆಯಾಗದಂತೆ ಬದುಕುವುದು ಅಹಿಂಸೆ. ನಾವು ಇನ್ನೊಬ್ಬರ ಮನಸ್ಸನ್ನು ಘಾಸಿಗೊಳಿಸಿದರೆ\nಅದನ್ನು ಮರಳಿ ವಾಸಿ ಮಾಡುವ ಯಾವ ಔಷಧವೂ ಇಲ್ಲ. ಆದ್ದರಿಂದ ಎಂದೂ ಇನ್ನೊಬ್ಬರನ್ನು\nಮುಖಭಂಗ ಮಾಡಬೇಡ. ಉದಾಹರಣೆಗೆ: ಒಬ್ಬರನ್ನು ಚುಚ್ಚು ಮಾತಿನಿಂದ ಹಂಗಿಸುವುದು,\nಮಾನಸಿಕವಾಗಿ ಇನ್ನೊಬ್ಬರನ್ನು ನಿಂದಿಸುವುದು ಅಥವಾ ಶಾಪ ಹಾಕುವುದು. ನಾವು ನಮ್ಮ ಮಾತಿನಿಂದ,\nಕೃತಿಯಿಂದ ಮತ್ತು ಮನಸ್ಸಿನಿಂದ ಇನ್ನೊಬ್ಬರಿಗೆ ಹಿಂಸೆಯಾಗದಂತೆ ನಡೆದುಕೊಳ್ಳಬೇಕು.\n\n(೧೧) ಸತ್ಯಮ್‌: ಇದು ಪ್ರಾಮಾಣಿಕತೆಯ ಇನ್ನೊಂದು ಮುಖ. ಇಲ್ಲಿ ಸತ್ಯ ಅಂದರೆ ಇದ್ದದ್ದನ್ನು ಇದ್ದಂತೆ\nಹೇಳುವುದಲ್ಲ. ಸಮಾಜದಲ್ಲಿ ಸಾದು ಸಜ್ಜನರಿಗೆ ಹಿತವಾಗುವಂತಹ ಮಾತು ಸತ್ಯ. ಕೆಲವೊಮ್ಮೆ ಲೋಕ\nಹಿತಕ್ಕೋಸ್ಕರ ನಾವು ಹೇಳುವ ಸುಳ್ಳೂ ಕೂಡಾ ಸತ್ಯವಾಗುತ್ತದೆ; ಲೋಕಕ್ಕೆ ಅನ್ಯಾಯವಾಗುವಂತಹ ಸತ್ಯವೂ\nಸುಳ್ಳಾಗುತ್ತದೆ. ಮಹಾಭಾರತದಲ್ಲಿ ಕೃಷ್ಣ ಈ ಸಂದೇಶವನ್ನು ಕ್ರಾಂತಿಕಾರಕ ರೂಪದಲ್ಲಿ ಮಾಡಿ ತೋರಿಸಿದ್ದಾನೆ.\nಈ ವಿಷಯ ಮಹಾಭಾರತದಲ್ಲಿ ವಿಶೇಷವಾಗಿ ಪ್ರಸ್ತಾಪವಾಗಿದೆ. ಅಲ್ಲಿ ಹೇಳುವಂತೆ:\n\nನ ನರ್ಮ ಯುಕ್ತಂ ವಚನಂ ಹಿನಸ್ತಿ ನ ಸ್ತ್ರೀಷು ರಾಜನ್‌ ನ ವಿವಾಹ ಕಾಲೇ\n\nಪ್ರಾಣಾತ್ಯಯೈ ಸರ್ವಧನಾಪಹಾರೇ ಪಂಚಾನೃತಾನ್ಯ ಆಹುರ್‌ ಅಪಾತ್‌ ಕಾನಿ ॥೧-೭೭-೧೬॥\n\nಒಬ್ಬರ ಮದುವೆಯನ್ನು ಹೊಟ್ಟೆಕಿಚ್ಚಿನಿಂದ ಸುಳ್ಳು ಹೇಳಿ ತಪ್ಪಿಸುವುದು, ನಿಶ್ಚಿತಾರ್ಥವಾಗಿರುವ ಮದುವೆಯನ್ನು\nತಪ್ಪಿ ಸುವುದು, ಇತ್ಯಾದಿಯನ್ನು ಶಾಸ್ತ್ರ ಖಂಡಿಸುತ್ತದೆ. ಪ್ರಾಣಾಪಾಯದ ಕಾಲದಲ್ಲಿ ಜೀವ ರಕ್ಷಣೆಗಾಗಿ ಹೇಳುವ\nಸುಳ್ಳು ಸುಳ್ಳಲ್ಲ.\n\n(೧೨) ಅಕ್ರೋಧಃ: ಯಾವ ಕಾಲಕ್ಕೂ ಇನ್ನೊಬ್ಬರ ಮೇಲೆ ಕೋಪಿಸಿಕೊಳ್ಳದೇ ಇರುವುದು. ಅಪ್ರಿಯ ಘಟನೆ\nನಡೆದಾಗ ಕೋಪ ಬರಬಹುದು. ಆದರೆ ನಿಮ್ಮನ್ನು ಕೋಪದ ಕೈಗೆ ಎಂದೂ ಕೊಡಬೇಡಿ. ಕೋಪಬಂದಾಗ-ಕೋಪ\nಇಳಿಯುವ ತನಕ ಮೌನವನ್ನಾಚರಿಸಿದರೆ ಅದರಿಂದಾಗುವ ಅನಾಹುತ ತಪ್ಪುತ್ತದೆ. ಕಾಮ-ಕ್ರೋದದ ಬಗ್ಗೆ ಕೃಷ್ಣ\nಗೀತೆಯಲ್ಲಿ ಅನೇಕ ಬಾರಿ ನಮ್ಮನ್ನು ಎಚ್ಚರಿಸುತ್ತಾನೆ. ನೆಮ್ಮದಿಯ ಜೀವನಕ್ಕೆ ಇವು. ಮಾರಕ. ಹೇಗೆ\nಶಾಂತತೆಯನ್ನು ನಾವು ಕಲಿತುಕೊಳ್ಳಬೇಕು. ಎನ್ನುವುದಕ್ಕೆ ಶ್ರೀರಾಮಚಂದ್ರನ ಜೀವನವೇ ಉತ್ತಮ\n\nಉದಾಹರಣೆ. ರಾಮಾಯಣದಲ್ಲಿ ವಾಲ್ಮೀಕಿ ಹೇಳುತ್ತಾರೆ: “ಉಚ್ಚಮಾನೋ$ಪಿ ಪರುಷಮ್‌ ನೋತ್ತರಂ\nಪ್ರತಿಪದ್ಯತೆ” ಎಂದು. ॥ಅಯೋಧ್ಯಾ-೧.೧೫॥ ರಾಮನಲ್ಲಿ ಯಾರಾದರೂ ಜಗಳಕ್ಕೆ ನಿಂತರೆ ಆತ ಎಂದೂ\nಸಿಟ್ಟಿಗೇಳುತ್ತಿರಲಿಲ್ಲವಂತೆ.\n\n(೧೩) ತ್ಯಾಗಃಃ ಮೇಲ್ನೋಟಕ್ಕೆ ದಾನ ಮತ್ತು ತ್ಯಾಗ ಒಂದೇ ಎನ್ನುವಂತೆ ಕಾಣಿಸುತ್ತದೆ. ಆದರೆ ತ್ಯಾಗ ಎಂದರೆ\nನಮ್ಮಲ್ಲಿರುವ ವಸ್ತುವೂ ಕೂಡಾ ನನ್ನದಲ್ಲ-ಭಗವಂತನದು ಎನ್ನುವ ಭಾವನೆಯಿಂದ ಬದುಕುವುದು. ತ್ಯಾಗದಲ್ಲಿ\nಅನೇಕ ವಿಧ. ಅಭಿಮಾನ ತ್ಯಾಗ, ಫಲ ತ್ಯಾಗ, ಅಹಂಕಾರ-ಮಮಕಾರ ತ್ಯಾಗ ಇತ್ಯಾದಿ. ಪ್ರೀತಿ ಇರಲಿ, ಆದರೆ\n'ನನ್ನದು' ಎನ್ನುವ ಭಾವನೆಯಿಂದ ದೂರ ನಿಲ್ಲು. ಬಂದಾಗ ಸಂತೋಷದಿಂದ ಸ್ವೀಕರಿಸು, ಹೋದಾಗ\nನಿರ್ಲಿಪ್ತನಾಗಿ ಇದ್ದು ಬಿಡು. ಈ ಜೀವನ ಪಯಣದಲ್ಲಿ ಯಾವುದೂ ಶಾಶ್ವತವಲ್ಲ. ಭಗವಂತನೊಬ್ಬನೇ ನಿತ್ಯ\nಎಂದು ತಿಳಿದು ಆತನನ್ನು ಗುರಿಯಿಟ್ಟು ಪಯಣಿಸು.\n\n(೧೪) ಶಾಂತಿಃ : ತ್ಯಾಗದಿಂದ ಮೊತ್ತ ಮೊದಲು ಸಿಗುವುದು ನೆಮ್ಮದಿ. ಸ್ವಲ್ಪವೂ ಉದ್ವೇಗಕ್ಕೆ ಒಳಗಾಗದೆ,\nಪ್ರತಿಯೊಂದನ್ನೂ ಸ್ವೀಕರಿಸಿದಾಗ ಎಲ್ಲವೂ ಶಾಂತ. ಮನಸ್ಸನ್ನು ಭಗವಂತನಲ್ಲಿ ನೆಲೆಗೊಳಿಸಿದಾಗ ಮಾತ್ರ\nಅಂತಹ ಶಾಂತಿ ಬರಲು ಸಾಧ್ಯ. ಕ್ಷುದ್ರವಾದ ಲೌಕಿಕ ವಿಚಾರದಲ್ಲಿ ತಲೆ ಹಾಕಿಕೊಂಡು- ಪೈಪೋಟಿ, ಸ್ಪರ್ಧೆ,\nಜಗಳ, ವಿರಸದಿಂದ ಜೀವನ ಸಾಗಿಸುವುದಕ್ಕಿಂತ ಭಗವಂತನಲ್ಲಿ ಮನಸ್ಸನ್ನು ನೆಲೆಗೊಳಿಸಿ ಶಾಂತಿಯನ್ನು\n(೧೫) ಅಪೈಶುನಮ್‌: 'ಪೈಶುನಮ್‌' ಅಂದರೆ ಚಾಡಿ ಹೇಳಿ ವಿರಸ ಹುಟ್ಟಿಸುವುದು. ಇದು ಅತ್ಯಂತ ನಿಕೃಷ್ಟ ಗುಣ.\nನಮ್ಮ ಸ್ವಾರ್ಥಕ್ಕಾಗಿ ದೊಡ್ಡವರಲ್ಲಿ ಚಾಡಿಹೇಳಿ, ಸಮಾಜ ಸ್ವಾಸ್ಥ್ಯ ವನ್ನು ಕೆಡಿಸುವುದು ಮಹಾ ಪಾಪ. ಆದ್ದರಿಂದ\nನೀನು ಅಪೈಶುನನಾಗು ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಚಾಡಿ ಹೇಳಬೇಡ ಮತ್ತು ಚಾಡಿಗೆ ಕಿವಿಗೊಡಬೇಡ.\n\n(೧೬) ದಯಾ ಭೂತೇಷು: ಚೈತನ್ಯವಿರುವ ಪ್ರತಿಯೊಂದು ಜೀವಿಗಳ ಮೇಲೆ ಅನುಕಂಪವಿರಲಿ. ಅದು ವನಸ್ಪತಿ\nಇರಲಿ, ಪ್ರಾಣಿ ಇರಲಿ, ಪಕ್ಷಿ ಇರಲಿ, ಮಾನುಷ್ಯನಿರಲಿ. ಎಲ್ಲರ ಮೇಲೂ ದಯೆ ಇರಲಿ. ಇದನ್ನು ಹಿಂದಿನ ಕಾಲದಲ್ಲಿ\nವಿಶೇಷ ರೀತಿಯಲ್ಲಿ ಅನುಸರಿಸಿಕೊಂಡು ಬರುತ್ತಿದ್ದರು. ಬೆಳಿಗ್ಗೆ ಎದ್ದು ತುಳಸಿಗೆ ನೀರು ಹಾಕುವುದು, ಗೋಶಾಲೆಗೆ\nಹೋಗಿ. ಹಸುಗಳಿಗೆ ಆಹಾರ ನೀಡುವುದು, ಮನೆಯಲ್ಲಿರುವ ನಾಯಿಗೆ ನಾವು ಊಟ ಮಾಡುವ ಮೊದಲು\nಆಹಾರ ನೀಡುವುದು, ಮನೆ ಸುತ್ತಮುತ್ತಲಿರುವ ಪಕ್ಷಿಗಳಿಗೆ ಆಹಾರ ಕೊಡುವುದು, ಹಸಿದು ಬಂದ ವ್ಯಕ್ತಿಯ\nಹೊಟ್ಟೆಯಲ್ಲಿರುವ ವೈಶ್ವಾನರನನ್ನು ತಣಿಸುವುದು ಇತ್ಯಾದಿ. ಇದಲ್ಲದೆ ಇನ್ನೊಬ್ಬರು ತೊಂದರೆಯಲ್ಲಿದ್ದಾಗ, ಆತ\nಮಿತ್ರ ಶತ್ರು ಎನ್ನುವ ಭೇದವೆಣಿಸದೇ ಅವರ ಮೇಲೆ ದಯೆ ತೋರುವುದು ಬಹಳ ದೊಡ್ಡ ಗುಣ. ಈ ಗುಣವನ್ನು\nಮುಖ್ಯವಾಗಿ ಮಹಾಭಾರತದಲ್ಲಿ ಧರ್ಮರಾಯನಲ್ಲಿ ಕಾಣುತ್ತೇವೆ.\n\n(೧೭) ಅಲೋಲುತ್ವಂ/ ಅಲೋಲತ್ವಂ: ಒಂದನ್ನು ಅತಿಯಾಗಿ ಹಚ್ಚಿಕೊಳ್ಳುವುದು ಲೋಲತ್ವ. ಯಾವುದರ\nಮೇಲೂ ಅತಿಯಾದ ಮೋಹ ಬೇಡ. ಅಂಟಿಸಿಕೊಳ್ಳುವುದು ದುಃಖಕ್ಕೆ ಕಾರಣ.\n\n(೧೮) ಮಾರ್ದವಂ(Gentle): ಸೌಜನ್ಯ, ಮೃದು ಸ್ವಭಾವವನ್ನು ಇಲ್ಲಿ ಮಾರ್ದವಂ ಎಂದಿದ್ದಾರೆ. ನಮ್ಮಲ್ಲಿ\nಕೆಲವರು ತಮ್ಮ ಕೆಲಸದವರನ್ನು, ಅಥವಾ ತಮ್ಮ ಕೈ ಕೆಳಗೆ ಕೆಲಸ ಮಾಡುವ ಸಹೋದ್ಯೋಗಿಗಳನ್ನು\nಗೌರವವಿಲ್ಲದೆ ಮಾತನಾಡಿಸುತ್ತಾರೆ. ಅವರು “ನನ್ನ ಸೇವಕರು' ಎಂದು ಅಹಂಕಾರದಿಂದ ಅವರೊಂದಿಗೆ\nವ್ಯವಹರಿಸುತ್ತಾರೆ. ಇದು ಅತ್ಯಂತ ನೀಚ ಗುಣ. ಇದರಿಂದಾಗಿ ನಾವು ಆ ವ್ಯಕ್ತಿಯ ಮನ ನೋಯಿಸುವುದಷ್ಟೇ\n\nಅಲ್ಲ, ಆತನ ಒಳಗಿರುವ ಭಗವಂತನನ್ನು ಧಿಕ್ಕರಿಸಿದಂತೆ. ಇದು ಅಹಂಕಾರದ ಇನ್ನೊಂದು ಮುಖ. ಅದಕ್ಕಾಗಿ\nಕೃಷ್ಣ ಹೇಳಿದ: “ನಿಮ್ಮ ನಡತೆಯಲ್ಲಿ ನಯ ವಿನಯವಿರಲಿ, ಸೌಜನ್ಯವಿರಲಿ” ಎಂದು.\n\n(೧೯) ಹ್ರೀಃ (ನಾಚಿಕೊಳ್ಳುವುದು): ತಪ್ಪು ಮಾಡಿದಾಗ ನಾಚಿಕೊಳ್ಳುವುದು. ಇದು ಬಹಳ ದೊಡ್ಡ ಗುಣ.\nತೈತ್ತಿರೇಯ ಉಪನಿಷತ್ತಿನಲ್ಲಿ ಹೇಳುವಂತೆ : | ಶ್ರೀಯಾ ದೇಯಂ | ಹ್ರೀಯಾ ದೇಯಂ | ಭಿಯಾ ದೇಯಂ |\nಸಂವಿದಾ ದೇಯಂ ॥೧೧-೦೩॥ ಇನ್ನೊಬ್ಬರು ಟೀಕೆ ಮಾಡಬಹುದು ಎನ್ನುವ ನಾಚಿಕೆಯಿಂದಾದರೂ ದಾನ\nಮಾಡು ಎನ್ನುತ್ತದೆ ಶಾಸ್ತ್ರ.\n\n(೨೦) ಅಚಾಪಲಮ್‌ : ಸ್ವಂತ ನಿರ್ಧಾರ ತೆಗೆದುಕೊಳ್ಳುವ ಸ್ಥೈರ್ಯ. ವಿಷಯ ವಿಶ್ಲೇಷಣೆ ಮಾಡಿ ಯಾವುದು ಸರಿ,\nಯಾವುದು ತಪ್ಪು ಎಂದು ತಿಳಿದು, ಯಾವುದು ನನ್ನ ದಾರಿ ಎಂದು ಗಟ್ಟಿಯಾಗಿ ನಿಲ್ಲುವುದು ಅಚಾಪಲಮ್‌.\n\n(೨೧) ತೇಜಃ (ತೇಜಸ್ಸು): ಇದನ್ನು ಶಾಸ್ತ್ರಕಾರರು ಬ್ರಹ್ಮವರ್ಚಸ್ಸು ಎನ್ನುತ್ತಾರೆ. ಮುಖದಲ್ಲಿ ಕಳೆ\nತುಂಬಿಕೊಂಡಿರುವುದು. ಕಣ್ಣಿನಲ್ಲಿ ತೇಜಸ್ಸು... ಮನಸ್ಸು ಸ್ವಚ್ಛವಿರುವ ಸಾಧನೆಯ ಮಾರ್ಗದಲ್ಲಿ ಸಾಗುವ\nಜ್ಞಾನಿಗಳಲ್ಲಿ ಮಾತ್ರ ಈ ಗುಣವಿರುತ್ತದೆ.\n\n(೨೨) ಕ್ಷಮಾ(Forgiveness): ತಪ್ಪು ಮಾಡಿದವರ ಮೇಲೆ ಕೂಡಾ ಪ್ರತೀಕಾರ ಭಾವನೆ ಬೆಳೆಸಿಕೊಳ್ಳದೇ\nಇರುವುದು. ನಮ್ಮ ಮನಸ್ಸಿನಲ್ಲಿ ಎಂದೂ ಪ್ರತೀಕಾರ ಭಾವನೆ ಹುಟ್ಟಲೇಬಾರದು. ಶಾಸ್ತ್ರದಲ್ಲಿ ಹೇಳುವಂತೆ:\n“ಇನ್ನೊಬ್ಬ ರು ಅಪಕಾರ ಮಾಡಿದರೂ ಕೂಡಾ ಅವರನ್ನು ಕ್ಷಮಿಸು” ಎಂದು. “ದೇವರೇ, ಅವರಿಗೆ ಒಳ್ಳೆಯ ಬುದ್ಧಿ\nಕೊಡು” ಎಂದು ಪ್ರಾರ್ಥಿಸು-ಆದರೆ. ಪ್ರತೀಕಾರದ ಭಾವನೆ ಬೇಡ. ನಮ್ಮಲ್ಲಿ “ಎಲ್ಲರೂ ನನ್ನನ್ನು\nಮೆಚ್ಚಿಕೊಳ್ಳಬೇಕು” ಎನ್ನುವ ಅಹಂಕಾರ ಇಲ್ಲದೇ ಇದ್ದರೆ ಮಾತ್ರ ಕ್ಷಮಾ ಸಾಧ್ಯ.\n\n(೨೩) ಧೃತಿಃ (ಏನೇ ಆದರೂ ಜೀವನದಲ್ಲಿ ಕಂಗೆಡದಿರುವುದು): ಆತ್ಮ ಭರವಸೆ ಇದ್ದಾಗ ನಮ್ಮನ್ನು ಯಾರೂ\nಏನೂ ಮಾಡಲು ಸಾಧ್ಯವಿಲ್ಲ. ನಿಜವಾದ ಜ್ಞಾನಿ ಎಂದೂ ಅಂಜುಬುರುಕನಾಗಿ ಧೃತಿಗೆಡುವುದಿಲ್ಲ. “ಮುಂದೆ\nಹೀಗಾಗಬಹುದು” ಎಂದು ಮನಸ್ಸಿನಲ್ಲಿ ಯೋಚಿಸಿಕೊಂಡು ಕೊರಗುವುದು ಜೀವನವಲ್ಲ, ಬದಲಿಗೆ ಏನೇ ಬಂದರು\nಅದನ್ನು ಎದುರಿಸುವ ಶಕ್ತಿ ಭಗವಂತ ನನಗೆ ಕೊಡುತ್ತಾನೆ ಎನ್ನುವ ಧೃಡವಾದ ಆತ್ಮಶಕ್ತಿ ಧೃತಿ. ವಿಷಮ\nಪರಿಸ್ಥಿತಿಯನ್ನು ಎದುರಿಸಿಕೊಂಡು ಬದುಕುವುದೇ ಜೀವನ. ಅನಿರೀಕ್ಷಿತ ಆಪತ್ತು ಜೀವನದಲ್ಲಿ ಸಾಮಾನ್ಯ.\nಅದನ್ನು ತಿಳಿದು ಆತ್ಮವಿಶ್ವಾಸದಿಂದ ಬದುಕು. ಆಗಬಾರದ್ದು ಈ ಜಗತ್ತಿನಲ್ಲಿ ಎಂದೂ ಆಗುವುದಿಲ್ಲ, ಆಗುವುದನ್ನು\nಯಾರಿಂದಲೂ ತಡೆಯಲು ಸಾಧ್ಯವಿಲ್ಲ. ನಮ್ಮ ರಕ್ಷಣೆಯ ಭಾರ ಸರ್ವನಿಯಾಮಕ ಭಗವಂತನದು. ಹೀಗಿರುವಾಗ\nಭಯವೇಕೆ?\n\n(೨೪) ಶೌಚಮ್‌: ಈ ವಿಷಯವಾಗಿ ಹಿಂದಿನ ಅಧ್ಯಾಯಗಳಲ್ಲಿ ಅನೇಕ ಬಾರಿ ಚರ್ಚಿಸಿದ್ದೇವೆ. ಶೌಚ ಎಂದರೆ\nಒಳಗೂ ಹೊರಗೂ ಸ್ವಚ್ಛವಾಗಿರುವುದು. ಸಮಾಜದಲ್ಲಿ ನಮ್ಮಿಂದಾಗಿ ಇತರರಿಗೆ ತೊಂದರೆಯಾಗಬಾರದು.\nನಮ್ಮ ಮೈಮನ ಸ್ವಚ್ಛವಾಗಿರುವಂತೆ ನಾವು ನೋಡಿಕೊಳ್ಳಬೇಕು. ಇದಕ್ಕಾಗಿ ಹಿಂದಿನ ಕಾಲದಲ್ಲಿ ಪ್ರತಿದಿನ\nಶುಭ್ರವಾದ ಗರಿ-ಗರಿಯಾದ ಬಟ್ಟೆಯನ್ನು ಧರಿಸುತ್ತಿದ್ದರು, ಮೈ ವಾಸನೆ ಬರಬಾರದು ಎಂದು ಮೃತ್ತಿಕಾ ಸ್ನಾನ\nಮಾಡುತ್ತಿದ್ದರು, ಮೈಗೆ ಗಂಧವನ್ನು ಬಳಿದುಕೊಳ್ಳುತ್ತಿದ್ದರು. ನಮ್ಮಿಂದಾಗಿ ಇನ್ನೊಬ್ಬರು 'ಅಯ್ಯೋ' ಎಂದು\nಮೂಗು ಮುರಿಯುವಂತೆ ನಾವಿರಬಾರದು. ನಮ್ಮ ಮನಸ್ಸು ಸ್ವಚ್ಛವಾಗಿರಬೇಕು. ಒಳ್ಳೆಯ ಬಟ್ಟೆ ತೊಟ್ಟು,\n\nಮನಸ್ಸಿನಲ್ಲಿ ಕಶ್ಮಲ ತುಂಬಿಕೊಂಡಿದ್ದರೆ ನಾವು ನಮಗರಿವಿಲ್ಲದಂತೆ ನಮ್ಮ ಸುತ್ತಮುತ್ತಲಿನ ವಾತಾವರಣವನ್ನು\nಕೆಡಿಸುತ್ತೇವೆ. ಇದಕ್ಕಾಗಿ ಒಳಗೂ ಹೊರಗೂ ಸ್ವಚ್ಛವಾಗಿರಬೇಕು.\n\n(೨೫) ಅದ್ರೋಹಃ: ಇನ್ನೊಬ್ಬರ ಬಗ್ಗೆ ದ್ರೋಹ ಚಿಂತನೆ ಮಾಡದಿರುವುದು. ಇನ್ನೊಬ್ಬರಿಗೆ ಎರಡೆಣಿಸಬೇಡ.\nಇನ್ನೊಬ್ಬರಿಗೆ ಕೆಟ್ಟದಾಗಲಿ ಎಂದು ಕನಸಿನಲ್ಲೂ ಬಯಸಬೇಡ.\n\n(೨೬) ನಾತಿಮಾನಿತಾ: “ಅತಿಮಾನ' ಅಂದರೆ ನನ್ನ ಬಗ್ಗೆ ನಾನು ಅತಿಯಾದ ಹೆಗ್ಗಳಿಕೆ ಕಲ್ಪಿಸಿಕೊಂಡು\nಬೀಗುವುದು. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ನಿನ್ನ ಬಗ್ಗೆ ನೀನು ಎಂದೂ ಅತಿಯಾದಂತಹ ಅಹಂಕಾರ ತಾಳಬೇಡ” ಎಂದು.\nಈ ಗುಣಕ್ಕೆ ಶ್ರೀರಾಮಚಂದ್ರನ ಜೀವನ ಉತ್ತಮ ದೃಷ್ಟಾಂತ. ವಾಲ್ಮೀಕಿ-ರಾಮಾಯಣದಲ್ಲಿ ಹೇಳುತ್ತಾರೆ:\n“ವೀರ್ಯವಾನ್‌ ನಚ ವೀರ್ಯೇನ ಮಹತಾ ಸ್ವೇನ ವಿಸ್ಮಿತಃ”॥|೨-೧-೧೩॥ ಎಂದು. ಅಸಾಧಾರಣ\nಪೌರುಷೇಯನಾಗಿದ್ದ ರಾಮ ಎಂದೂ “ನಾನು ಮಹಾವೀರ” ಎಂದು ಅಹಂಕಾರ ಪಡದೆ, ಒಬ್ಬ ಸಾಮಾನ್ಯ\nಮಾನವನಂತೆ ಬದುಕಿ ತೋರಿಸಿದ. ಇದು ಬಹು ದೊಡ್ಡ ಗುಣ.\n\nಹೀಗೆ ನಾವು ಜೀವನದಲ್ಲಿ ಅಳವಡಿಸಿಕೊಳ್ಳಬೇಕಾದ ಇಪ್ಪತ್ತಾರು ಗುಣಗಳನ್ನು ಹೇಳಿ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ:\n“ಭವಂತಿ ಸಂಪದಂ ದೈವೀಮಭಿಜಾತಸ್ಯ ಭಾರತ” ಎಂದು. ಇಲ್ಲಿ \"ಅಭಿ' ಅಂದರೆ 'ಬಯಸಿ' ಎನ್ನುವ ಅರ್ಥವನ್ನು\nಕೊಡುತ್ತದೆ. “ದೈವೀ ಸಂಪತ್ತನ್ನು ಬಯಸಿ ಹುಟ್ಟಿದವನಲ್ಲಿ ಈ ಗುಣಗಳಿರುತ್ತವೆ. ಅಂದರೆ ಯಾರು\nಹುಟ್ಟುವಾಗಲೇ ಸಾತ್ವಿಕತೆಯ ಅಭಿಲಾಷೆಯನ್ನು ಇಟ್ಟುಕೊಂಡು ಹುಟ್ಟುತ್ತಾರೋ ಅವರಿಗೆ ಸಹಜವಾಗಿ ಈ\nಗುಣಗಳಿರುತ್ತವೆ. ಇವು ದೈವೀ ಸಂಪತ್ತು. ಮಾನವನು ಬೆಳಸಿಕೊಳ್ಳಬೇಕಾದ ಮಾನಸಿಕ ಸಂಪತ್ತು.\n",
  "16.4": "ಡಂಭಃ ದರ್ಪಃ ಅಭಿಮಾನಃ ಚ ಕ್ರೋಧಃ ಪಾರುಷ್ಯಮ್‌ ಏವಚ ।\nಅಜ್ಞಾನಮ್‌ ಚ ಅಭಿಜಾತಸ್ಯ ಪಾರ್ಥ ಸಂಪದಮ್‌ ಆಸುರೀಮ್‌- ಪಾರ್ಥಾ, ಆಸುರೀ ಸಂಪತ್ತು [ಕೆಟ್ಟ ನಡತೆ]\nಹೊತ್ತು ಬಂದವನ ಗುಣಗಳು ಇವು: ಬೂಟಾಟಿಕೆ, ಸೊಕ್ಕು, ಬಿಂಕ, ಸಿಡುಕು, ಒರಟುತನ ಮತ್ತು ತಿಳಿಗೇಡಿತನ.\n\nಮೇಲೆ ಹೇಳಿದ ಇಪ್ಪಾತ್ತಾರು ದೈವೀಗುಣಕ್ಕೆ ವಿರುದ್ಧವಾಗಿ ಆರು ಆಸುರೀ ಗುಣಗಳನ್ನು ಕೃಷ್ಣ ಈ ಶ್ಲೋಕದಲ್ಲಿ\nಹೇಳಿದ್ದಾನೆ:\n\n(೧) ಡಂಭ(ಇಲ್ಲದ್ದನ್ನು ಇದೆ ಎಂದು ತೋರಿಸಿಕೊಳ್ಳುವುದು): ಒಳಗಡೆ ಏನಿಲ್ಲವೋ ಅದು ಇದೆ ಎನ್ನುವಂತೆ\nಸುಭಗತನದ ಪ್ರದರ್ಶನ; ಒಳಗಿರುವ ಕೆಟ್ಟತನವನ್ನು ಮುಚ್ಚಿಟ್ಟು ತುಂಬಾ ಒಳ್ಳೆಯವರ ಹಾಗೆ ಪ್ರದರ್ಶನ\nಮಾಡುವುದು, ಇತ್ಯಾದಿ ಡಂಭ ಎನಿಸುತ್ತದೆ. ಇದು ಮೇಲೆ ಹೇಳಿದ ಅರ್ಜವಂ ಎನ್ನುವ ಸದ್ಗುಣದ ವಿರುದ್ಧ ಗುಣ.\n(೨) ದರ್ಪ: ಏನು ತಪ್ಪು ಮಾಡಲೂ ಹೇಸದ ಮನೋವೃತ್ತಿ. ಇದು ಹ್ರೀ ಎನ್ನುವ ಸದ್ಗುಣದ ವಿರುದ್ಧ ಗುಣ.\n\n(೩) ಅತಿಮಾನ: ತನ್ನ ಬಗ್ಗೆ ಅತಿರೇಕದ ಕಲ್ಪನೆ; ನಾನೇ ದೊಡ್ಡ ಮನುಷ್ಯ ಎಂದು\nಭ್ರಮಿಸಿಕೊಂಡು ಇನ್ನೊಬ್ಬರಿಗೆ ಅಗೌರವ ತೋರುವುದು; ಎಲ್ಲರೂ ತನ್ನ ಕಾಲನ್ನು ಹಿಡಿಯಬೇಕು ಎಂದು\nಅಪೇಕ್ಷಿಸುವುದು-ಇವು ಅತಿಮಾನವೆನಿಸುತ್ತವೆ.\n\n(೪) ಕ್ರೋಧ : ಮನುಷ್ಯ ಬಿಡಬೇಕು ಎಂದರೂ ಬಿಡಲಾಗದ ಕೆಟ್ಟಗುಣ ಕ್ರೋಧ. ಇದು ನಮಗೆ ಗೊತ್ತಿಲ್ಲದಂತೆ\nನಮ್ಮನ್ನು ದಾರಿತಪ್ಪಿಸುವ ದುರ್ಗುಣ.\n\n(೫) ಪಾರುಷ್ಯ : ಉಗ್ರವಾದ, ಅಸಹ್ಯವಾದ ಮಾತು; ಇನ್ನೊಬ್ಬ ರನ್ನು ತಾತ್ಸಾರದಿಂದ ಮಾತನಾಡಿಸುವುದು,\nಇತ್ಯಾದಿ ಪಾರುಷ್ಯಕ್ಕೆ ಉದಾಹರಣೆ.\n\n(೬) ಅಜ್ಞಾನ : ಮೇಲಿನ ಎಲ್ಲಾ ದುರ್ಗುಣಗಳ ಚಕ್ರವರ್ತಿ ಈ ಅಜ್ಞಾನ. ನಿಜವಾದ ಜ್ಞಾನಿ ಎಂದೂ ಈ ಕೆಟ್ಟ\nಗುಣಗಳ ದಾಸನಾಗುವುದಿಲ್ಲ.\n\nಈ ಎಲ್ಲಾ ಅಸುರೀ ಗುಣಗಳು ನಮ್ಮಲ್ಲಿ ಮನೆ ಮಾಡಿ ನಮ್ಮನ್ನೇ ಹೊರ ಹಾಕುತ್ತವೆ. ಆದ್ದರಿಂದ ಈ\nದುರ್ಗುಣಗಳನ್ನು ನಾವು ಮೊದಲು ಹೊರ ಹಾಕಬೇಕು. ಕುರಾನಿನಲ್ಲಿ ಇದನ್ನು - “ದಿ1೪ಅ 07077 ೦೮! 1017 ೫೧೦೯೮\n೫೦೮ 03%ಆ 0೦೦೧ 61067 ೦೮” ಎಂದು ಸುಂದರವಾಗಿ ಹೇಳಿದ್ದಾರೆ. ನಿನ್ನ ನ್ನು ಹೊರಹಾಕಿ, ನಿನ್ನೊ ಳಗೆ ಕೂತು\nನಿನ್ನನ್ನು ಹಾಳು ಮಾಡುತ್ತಿರುವ ಈ ದುರ್ಗುಣಗಳನ್ನು ಮೊದಲು ಹೊರಹಾಕು ಎನ್ನುತ್ತಾರೆ. ಇದನ್ನೇ ವೇದದಲ್ಲಿ\nಹೀಗೆ ಹೇಳಿದ್ದಾರೆ: “ಯೊ ಅಸ್ಮಾನ್‌ ದ್ವೇಷ್ಟಿ ಯಾಮ್‌ ವಯಮ್‌ ದ್ವಿಷ್ಟಿಃ” ..|[ಅಥರ್ವ ೩-೨೭-೨|- ಅಂದರೆ-\n“ಯಾರು ನಮ್ಮನ್ನು ದ್ವೇಶಿಸುತ್ತಾರೋ, ಯಾರನ್ನು ನಾವು ದ್ವೇಷ ಮಾಡುತ್ತೇವೋ ಅಂತಹ ಶತ್ರುವನ್ನು\nಒದ್ದೋಡಿಸು” ಎಂದರ್ಥ. ಇಲ್ಲಿ ಶತ್ರು ಎಂದರೆ ನಮ್ಮ ಅಂತಃಶತ್ರುಗಳಾದ ಈ ದುರ್ಗುಣಗಳು.\n\nಈ ಶ್ಲೋಕದಲ್ಲಿ 'ಪಾರ್ಥ' ಎನ್ನುವ ವಿಶೇಷಣವನ್ನು ಬಳಸಲಾಗಿದೆ. “ನಾವು ದುರ್ಗುಣಗಳಿಂದ ದೂರ ಸರಿದು,\nಜ್ಞಾನ ಮಾರ್ಗದಲ್ಲಿ ಸಾಗಿ, ಯಥಾರ್ಥ ಬದುಕನ್ನು ಬದುಕುವ ಪಾರ್ಥರಾಗಬೇಕು' ಎನ್ನುವ ಸಂದೇಶ ಈ\nವಿಶೇಷಣದ ಹಿಂದಿದೆ.\n",
  "16.5": "ದೈವೀ ಸಂಪತ್‌ ವಿಮೋಕ್ಷಾಯ ನಿಬಂಧಾಯ ಆಸುರೀ ಮತಾ |\n\nಮಾ ಶುಚಃ ಸಂಪದಮ್‌ ದೈವೀಮ್‌ ಅಭಿಜಾತಃ ಅಸಿ ಪಾಂಡವಾ -ಒಳ್ಳೆಯ ನಡತೆ ಬಿಡುಗಡೆಯ ದಾರಿ.\nಕೆಡುನಡೆ. ತಮಸ್ಸಿನ ಸೆರೆಯ ದಾರಿ. ಪಾಂಡವ, ಕೊರಗಬೇಡ. ನೀನು ಒಳಿತಿನ ದಾರಿಯನ್ನು\nಮೈಗೂಡಿಸಿಕೊಂಡವನು.\n\nಏಕೆ ದೈವೀ ಸಂಪತ್ತನ್ನು ನಾವು ಬೆಳಸಿಕೊಳ್ಳಬೇಕು ಎನ್ನುವುದನ್ನು ಕೃಷ್ಣ ವಿವರಿಸುತ್ತಾ ಹೇಳುತ್ತಾನೆ: “ದೈವೀ\nಸಂಪತ್ತು ವಿಮೋಕ್ಷಕ್ಕೆ ಕಾರಣವಾಗುತ್ತದೆ, ಆಸುರೀ ಸ್ವಭಾವ ನಿಬಂಧಕ್ಕೆ ಕಾರಣವಾಗುತ್ತದೆ” ಎಂದು. ಇಲ್ಲಿ ಕೃಷ್ಣ\n'ವಿ-ಮೋಕ್ಷ' ಮತ್ತು 'ನಿ-ಬಂಧ' ಎಂದು ವಿಶೇಷವಾಗಿ ಹೇಳಿದ್ದಾನೆ. ವಿ-ಮೋಕ್ಷ ಎಂದರೆ ಅವರವರ ಸಾಧನೆಗೆ\n\nತಕ್ಕಂತೆ ವಿವಿಧ ಸ್ಥರದಲ್ಲಿ ವ್ಯಕ್ತಿತ್ವ ವಿಕಾಸ ಮತ್ತು ಮೋಕ್ಷ. 'ನಿ-ಬಂಧ' ಎಂದರೆ ಸಂಸಾರ ಬಂಧವಲ್ಲ. ಇದು ನೀಚ\nಬಂಧ. ನಮ್ಮನ್ನು ಕತ್ತಲೆಯ ತಮಸ್ಸಿಗೆ ತಳ್ಳುವ ಬಂಧ.\n\nಕೃಷ್ಣ ಅರ್ಜುನನನ್ನು ಕುರಿತು ಹೇಳುತ್ತಾನೆ: “ನೀನು ದೈವೀ ಸಂಪತ್ತಿನ ಪೂರ್ಣಪ್ರಮಾಣದ ಆವಿಷ್ಕಾರ. ಅದಕ್ಕಾಗಿ\nದೈವೀ ಸಂಪತ್ತಿನ ಮನೆಯನ್ನು ಹುಡುಕಿ ಹುಟ್ಟಿದ್ದೀಯ, ನಿನ್ನ ಸ್ವಭಾವ ಮತ್ತು ನೀನು ಹುಟ್ಟಿದ ಮನೆತನದ\nಪ್ರಭಾವ ಒಂದಕ್ಕೊಂದು ಪೂರಕ, ಇದಕ್ಕಾಗಿ ಚಿಂತಿಸಬೇಡ” ಎಂದು.\n\nದ್ವೌ ಭೂತಸರ್ಗೌ್‌ ಲೋಕೇಃಸ್ಮಿನ್‌ ದೈವ ಆಸುರ ಏವ ಚ |\nದೈವೋ ವಿಸ್ತರಶಃ ಪ್ರೋಕ್ತ ಆಸುರಂ ಪಾರ್ಥ ಮೇ ಶೃಣು 1೬\n\nದ್ವೌ ಭೂತಸರ್ಗೌ ಲೋಕೇ ಅಸ್ಮಿನ್‌ ದೈವಃ ಆಸುರಃ ಏವ ಚ |\n\nದೈವಃ ವಿಸ್ತರಶಃ ಪ್ರೋಕ್ತಃ ಆಸುರಮ್‌ ಪಾರ್ಥ ಮೇ ಶೃಣು -ಈ ವಿಶ್ವದಲ್ಲಿ ಎರಡು ಬಗೆಯ ಜೀವಸೃಷ್ಟಿಗಳಿವೆ:\nದೈವ[ಒಳ್ನಡೆಯದು] ಮತ್ತು ಆಸುರ [ಕೆಡುನಡೆಯದು]. ಒಳ್ನಡೆಯ ಬಗೆಯನ್ನು ಬಿತ್ತರಿಸಿ ಹೇಳಿದ್ದಾಯಿತು,\nಪಾರ್ಥಾ, ಕೆಡುನಡೆಯ ಬಿತ್ತರವನ್ನು ನನ್ನಿಂದ ಕೇಳು.\n\nಈ ವಿಶ್ವದಲ್ಲಿ ಮೂಲಭೂತವಾಗಿ ಎರಡು ಬಗೆಯ ಮಾನವರಿದ್ದಾರೆ: ಭಗವಂತನೆಡೆಗೆ ಮುಖ ಮಾಡಿ ಸಾಗುವ\nದೈವೀ ನಡೆಯುಳ್ಳವರು ಮತ್ತು ಭಗವಂತನಿಗೆ ಬೆನ್ನು ಹಾಕಿ ಸಾಗುವ ಆಸುರೀ ನಡೆಯವರು. ಈ ಎರಡು\nವಿಭಾಗದಲ್ಲಿ ಇಲ್ಲಿಯ ತನಕ ದೈವೀ ಸ್ವಭಾವದ ಬಗ್ಗೆ ವಿಸ್ತಾರವಾಗಿ ನೋಡಿದೆವು. ನಮ್ಮ ಆಂತರಿಕ ಮತ್ತು\nಸಾಮಾಜಿಕ ನಡೆಯ ಬಗ್ಗೆ ವಿಸ್ತಾರವಾದ ಚಿತ್ರಣ ಕೊಟ್ಟ ಬಳಿಕ ಕೃಷ್ಣ, ಇಲ್ಲಿ ಆಸುರೀ ಸ್ವಭಾವದವರ ನಡೆ-\nನುಡಿಗಳ ಬಗ್ಗೆ ವಿವರಿಸುತ್ತಾನೆ. ಈ ಮೂಲಕ ನಾವು “ಯಾವ ರೀತಿ ಇರಬಾರದು' ಎನ್ನುವುದನ್ನು ಕೃಷ್ಣ ನಮಗೆ\nತಿಳಿಸಿ ಹೇಳುತ್ತಾನೆ.",
  "16.6": "ದೈವೀ ಸಂಪತ್‌ ವಿಮೋಕ್ಷಾಯ ನಿಬಂಧಾಯ ಆಸುರೀ ಮತಾ |\n\nಮಾ ಶುಚಃ ಸಂಪದಮ್‌ ದೈವೀಮ್‌ ಅಭಿಜಾತಃ ಅಸಿ ಪಾಂಡವಾ -ಒಳ್ಳೆಯ ನಡತೆ ಬಿಡುಗಡೆಯ ದಾರಿ.\nಕೆಡುನಡೆ. ತಮಸ್ಸಿನ ಸೆರೆಯ ದಾರಿ. ಪಾಂಡವ, ಕೊರಗಬೇಡ. ನೀನು ಒಳಿತಿನ ದಾರಿಯನ್ನು\nಮೈಗೂಡಿಸಿಕೊಂಡವನು.\n\nಏಕೆ ದೈವೀ ಸಂಪತ್ತನ್ನು ನಾವು ಬೆಳಸಿಕೊಳ್ಳಬೇಕು ಎನ್ನುವುದನ್ನು ಕೃಷ್ಣ ವಿವರಿಸುತ್ತಾ ಹೇಳುತ್ತಾನೆ: “ದೈವೀ\nಸಂಪತ್ತು ವಿಮೋಕ್ಷಕ್ಕೆ ಕಾರಣವಾಗುತ್ತದೆ, ಆಸುರೀ ಸ್ವಭಾವ ನಿಬಂಧಕ್ಕೆ ಕಾರಣವಾಗುತ್ತದೆ” ಎಂದು. ಇಲ್ಲಿ ಕೃಷ್ಣ\n'ವಿ-ಮೋಕ್ಷ' ಮತ್ತು 'ನಿ-ಬಂಧ' ಎಂದು ವಿಶೇಷವಾಗಿ ಹೇಳಿದ್ದಾನೆ. ವಿ-ಮೋಕ್ಷ ಎಂದರೆ ಅವರವರ ಸಾಧನೆಗೆ\n\nತಕ್ಕಂತೆ ವಿವಿಧ ಸ್ಥರದಲ್ಲಿ ವ್ಯಕ್ತಿತ್ವ ವಿಕಾಸ ಮತ್ತು ಮೋಕ್ಷ. 'ನಿ-ಬಂಧ' ಎಂದರೆ ಸಂಸಾರ ಬಂಧವಲ್ಲ. ಇದು ನೀಚ\nಬಂಧ. ನಮ್ಮನ್ನು ಕತ್ತಲೆಯ ತಮಸ್ಸಿಗೆ ತಳ್ಳುವ ಬಂಧ.\n\nಕೃಷ್ಣ ಅರ್ಜುನನನ್ನು ಕುರಿತು ಹೇಳುತ್ತಾನೆ: “ನೀನು ದೈವೀ ಸಂಪತ್ತಿನ ಪೂರ್ಣಪ್ರಮಾಣದ ಆವಿಷ್ಕಾರ. ಅದಕ್ಕಾಗಿ\nದೈವೀ ಸಂಪತ್ತಿನ ಮನೆಯನ್ನು ಹುಡುಕಿ ಹುಟ್ಟಿದ್ದೀಯ, ನಿನ್ನ ಸ್ವಭಾವ ಮತ್ತು ನೀನು ಹುಟ್ಟಿದ ಮನೆತನದ\nಪ್ರಭಾವ ಒಂದಕ್ಕೊಂದು ಪೂರಕ, ಇದಕ್ಕಾಗಿ ಚಿಂತಿಸಬೇಡ” ಎಂದು.\n\nದ್ವೌ ಭೂತಸರ್ಗೌ್‌ ಲೋಕೇಃಸ್ಮಿನ್‌ ದೈವ ಆಸುರ ಏವ ಚ |\nದೈವೋ ವಿಸ್ತರಶಃ ಪ್ರೋಕ್ತ ಆಸುರಂ ಪಾರ್ಥ ಮೇ ಶೃಣು 1೬\n\nದ್ವೌ ಭೂತಸರ್ಗೌ ಲೋಕೇ ಅಸ್ಮಿನ್‌ ದೈವಃ ಆಸುರಃ ಏವ ಚ |\n\nದೈವಃ ವಿಸ್ತರಶಃ ಪ್ರೋಕ್ತಃ ಆಸುರಮ್‌ ಪಾರ್ಥ ಮೇ ಶೃಣು -ಈ ವಿಶ್ವದಲ್ಲಿ ಎರಡು ಬಗೆಯ ಜೀವಸೃಷ್ಟಿಗಳಿವೆ:\nದೈವ[ಒಳ್ನಡೆಯದು] ಮತ್ತು ಆಸುರ [ಕೆಡುನಡೆಯದು]. ಒಳ್ನಡೆಯ ಬಗೆಯನ್ನು ಬಿತ್ತರಿಸಿ ಹೇಳಿದ್ದಾಯಿತು,\nಪಾರ್ಥಾ, ಕೆಡುನಡೆಯ ಬಿತ್ತರವನ್ನು ನನ್ನಿಂದ ಕೇಳು.\n\nಈ ವಿಶ್ವದಲ್ಲಿ ಮೂಲಭೂತವಾಗಿ ಎರಡು ಬಗೆಯ ಮಾನವರಿದ್ದಾರೆ: ಭಗವಂತನೆಡೆಗೆ ಮುಖ ಮಾಡಿ ಸಾಗುವ\nದೈವೀ ನಡೆಯುಳ್ಳವರು ಮತ್ತು ಭಗವಂತನಿಗೆ ಬೆನ್ನು ಹಾಕಿ ಸಾಗುವ ಆಸುರೀ ನಡೆಯವರು. ಈ ಎರಡು\nವಿಭಾಗದಲ್ಲಿ ಇಲ್ಲಿಯ ತನಕ ದೈವೀ ಸ್ವಭಾವದ ಬಗ್ಗೆ ವಿಸ್ತಾರವಾಗಿ ನೋಡಿದೆವು. ನಮ್ಮ ಆಂತರಿಕ ಮತ್ತು\nಸಾಮಾಜಿಕ ನಡೆಯ ಬಗ್ಗೆ ವಿಸ್ತಾರವಾದ ಚಿತ್ರಣ ಕೊಟ್ಟ ಬಳಿಕ ಕೃಷ್ಣ, ಇಲ್ಲಿ ಆಸುರೀ ಸ್ವಭಾವದವರ ನಡೆ-\nನುಡಿಗಳ ಬಗ್ಗೆ ವಿವರಿಸುತ್ತಾನೆ. ಈ ಮೂಲಕ ನಾವು “ಯಾವ ರೀತಿ ಇರಬಾರದು' ಎನ್ನುವುದನ್ನು ಕೃಷ್ಣ ನಮಗೆ\nತಿಳಿಸಿ ಹೇಳುತ್ತಾನೆ.",
  "16.7": "ಪ್ರವೃತ್ತಿಮ್‌ ಚ ನಿವೃತ್ತಿಮ್‌ ಚ ಜನಾಃ ನ ವಿದುಃ ಆಸುರಾಃ ।\n\nನ ಶೌಚಮ್‌ ನ ಅಪಿ ಚ ಆಚಾರಃ ನ ಸತ್ಯಮ್‌ ತೇಷು ವಿದ್ಯತೇ -ಕೆಡುನಡೆಯ ಮಂದಿ ಯಾವ ದಾರಿ\nಹಿಡಿಯಬೇಕು, ಯಾವುದನ್ನು ಬಿಡಬೇಕು ಎಂಬುದನ್ನರಿಯರು. ಮಡಿಯಿಲ್ಲ; ಒಳ್ಳೆಯ ನಡೆಯಿಲ್ಲ; ಅವರಲ್ಲಿ ದಿಟದ\nನುಡಿಯಿಲ್ಲ.\n\nಆಸುರೀ ಸ್ವಭಾವದವರ ಸಾಮಾಜಿಕ ನಡೆ-ನುಡಿಯನ್ನು ಕೃಷ್ಣ ಇಲ್ಲಿ ವಿವರಿಸುತ್ತಾನೆ. ಆಸುರೀ ಸ್ವಭಾವದವರಿಗೆ\nಯಾವುದು ಮಾಡಬೇಕು, ಯಾವುದು ಮಾಡಬಾರದು ಎನ್ನುವ ಎಚ್ಚರವಿರುವುದಿಲ್ಲ. ಇದರಿಂದ ಅವರು\n\nಮಾಡಬಾರದ್ದನ್ನೇ ಮಾಡುತ್ತಿರುತ್ತಾರೆ. ಇವರಿಗೆ ನ್ಯಾಯ ಅನ್ಯಾಯ ಯಾವುದೂ ಮುಖ್ಯವಲ್ಲ. ಹಣ ಸಂಪಾದನೆ\nಮತ್ತು ಗಣ್ಯವ್ಯಕ್ತಿ ಸ್ಥಾನ ಗಳಿಸಬೇಕು ಎನ್ನುವುದು ಇವರ ಮೂಲಭೂತ ಬಯಕೆ. ಇದರಿಂದಾಗಿ ಹಣ\nಸಂಪಾದನೆಯಲ್ಲಿ ನ್ಯಾಯದ ಮುಖವಿರಬೇಕು ಎನ್ನುವ ಎಚ್ಚರ ಇವರಿಗಿರುವುದಿಲ್ಲ.\n\nಮೂಲಭೂತವಾಗಿ ಆಸುರೀ ಸ್ವಭಾವದವರಲ್ಲಿ ನೈರ್ಮಲ್ಯವಿರುವುದಿಲ್ಲ. ಒಳ್ಳಯಮಾತು, ಒಳ್ಳೆಯ ಯೋಚನೆ,\nಸ್ವಚ್ಛ ಶರೀರ ಇವರಲ್ಲಿರುವುದಿಲ್ಲ. ಇವರು ಬಾಹ್ಯವಾಗಿ ಬಹಳ ಶುದ್ಧರಂತೆ ನಾಟಕವಾಡಿಕೊಂಡು\nಬದುಕುತ್ತಿರುತ್ತಾರೆ. ಇವರು ಎಂದೂ ಪ್ರಾಮಾಣಿಕರಾಗಿರುವುದಿಲ್ಲ. ಏನು ಮಾಡಿದರೂ ಅದು ತೋರಿಕೆಗಾಗಿ.\nನಮಗೆ ಕೃಷ್ಣ ಗೀತೆಯಲ್ಲಿ ಹೇಳುವ ಒಂದೊಂದು ಗುಣ ನಡತೆಗೆ ಉದಾಹರಣೆ ಮಹಾಭಾರತದಲ್ಲೇ ಸಿಗುತ್ತದೆ.\nಅದಕ್ಕಾಗಿ ಗೀತೆಯನ್ನು ಮಹಾಭಾರತದ ಸಾರ ಎನ್ನು ವುದು. ಆಸುರೀ ಸ್ವಭಾವಕ್ಕೆ ಅತ್ಯುತ್ತಮ ಉದಾಹರಣೆ\n“ದುರ್ಯೋಧನ”.\n\nಈ ಆಸುರೀ ಸ್ವಭಾವದವರು ಹೇಗೆ ಸಮಾಜ ಕಂಟಕರಾಗುತ್ತಾರೆ, ಅವರ ತಿಳುವಳಿಕೆ ಏನು? ಎನ್ನುವುದನ್ನು ಈ\nಅಧ್ಯಾಯದ ಮುಂದಿನ ಭಾಗದಲ್ಲಿ ಕೃಷ್ಣ ವಿಸ್ತಾರವಾಗಿ ವಿವರಿಸುತ್ತಾನೆ.",
  "16.8": "ಅಸತ್ಯಮ್‌ ಅಪ್ರತಿಷ್ಠಮ್‌ ತೇ ಜಗತ್‌ ಆಹುಃ ಅನೀಶ್ವರಮ್‌ |\n\nಅಪರಸ್ಪರ ಸಂಭೂತಂ ಕಿಮ್‌ ಅನ್ಯತ್‌ ಕಾಮಹೈತುಕಮ್‌ - ಅವರು ಈ ವಿಶ್ವ ಸತ್ಯ ಸ್ವರೂಪನಾದ ಭಗವಂತನ\nಕೊಡುಗೆಯಲ್ಲ [ಇದೊಂದು ಸುಳ್ಳಿನ ಕಂತೆ] ಎನ್ನುತ್ತಾರೆ. ಇದು ಭಗವಂತನಲ್ಲಿ ನೆಲೆಗೊಂಡದ್ದಲ್ಲ [ಇದಕ್ಕೆ ಇರುವೇ\nಇಲ್ಲ] ಎನ್ನುತ್ತಾರೆ. ಇದನ್ನು ನಿಯಮಿಸುವ ಸರ್ವಶಕ್ತನೊಬ್ಬನಿಲ್ಲ ಎನ್ನುತ್ತಾರೆ. ಒಂದರಿಂದ ಇನ್ನೊಂದು ಕ್ರಮವಾಗಿ\nಹುಟ್ಟಿತು ಎನ್ನುವುದನ್ನೂ ಒಪ್ಪುವುದಿಲ್ಲ. ಮತ್ತೇನು? ಅವರ ದೃಷ್ಟಿಯಲ್ಲಿ ಇದೊಂದು ಬೇರೆಯ ತರ. ಇದೊಂದು\nಕಾಮದ ಕೂಸು-ಮಾಯಾಷಸ್ಕ ಷ್ಟಿ.\n\nಅಸುರರಲ್ಲಿ ಎರಡು ವಿಧ. ಜಗತ್ತಿಗೆ ಇನ್ನೊಂದು ಸತ್ಯವಿಲ್ಲ, ಜಗತ್ತಿಗೆ ಇನ್ನೊಂದು ಪ್ರತಿಷ್ಠೆ ಇಲ್ಲ, ಜಗತ್ತಿಗೆ ಇನ್ನೊಬ್ಬ\nಈಶ್ವರನಿಲ್ಲ ಎನ್ನುವ ನಾಸ್ತಿಕ ತಿಳುವಳಿಕೆ ಇವರಿಗಿರುತ್ತದೆ. ಜಗತ್ತನ್ನು ಸೃಷ್ಟಿ-ಸ್ಥಿತಿ-ಸಂಹಾರಗಳಿಗೆ ಒಳಪಡಿಸುವ\nಶಕ್ತಿ(ಸತ್ಯ) ಇಲ್ಲ ಎಂದು ಇವರು ತಿಳಿದಿರುತ್ತಾರೆ. ಇವರು ಈ ಜಗತ್ತಿಗೆ ಆಧಾರನಾಗಿ ಒಬ್ಬ ದೇವರಿಲ್ಲ, ಆದ್ದರಿಂದ\nಈ ಜಗತ್ತನ್ನು ನಿಯಂತ್ರಿಸುವ ಸ್ವಾಮಿ ಇಲ್ಲ, ಎಲ್ಲವೂ ಭ್ರಮೆ ಎಂದು ವಾದ ಮಾಡುತ್ತಾರೆ. ಸೃಷ್ಟಿಚಕ್ರ ಒಂದು\nಮೂರ್ಬತನದ ಸಿದ್ಧಾಂತ ಎನ್ನುವುದು ಇವರ ನಂಬಿಕೆ.\n\nಇನ್ನೊಂದು ವಿಧದ ಅಸುರರು ಈ ಜಗತ್ತಿನಲ್ಲಿ ನಮಗೆ ಏನು ಕಾಣುತ್ತದೋ ಅದು ಕೇವಲ ನಮ್ಮ ಭ್ರಮೆ ಎಂದು\nಶೂನ್ಯವಾದ ಮಾಡುವವರು. ಇವರು ಈ ಪ್ರಪಂಚ ನಮ್ಮ ಬಯಕೆಗಳಿಂದ ಬೆಳೆಯುತ್ತಿದೆಯೇ ಹೊರತು\nಇನ್ನೊಂದು ಶಕ್ತಿಯಿಂದಲ್ಲ ಎಂದು ನಂಬಿರುತ್ತಾರೆ.\n\nಏತಾಂ ದೃಷ್ಟಿಮವಷ್ಟ ಭ್ಯ ನಷ್ಟಾತ್ಮಾನೋಲ್ಬ ಬುದ್ಧಯಃ |\nಪ್ರಭವಂತ್ಯುಗ್ರಕರ್ಮಾಣಃ ಕ್ಷಯಾಯ ಜಗತೋಹಿತಾಃ",
  "16.9": "ಅಸತ್ಯಮ್‌ ಅಪ್ರತಿಷ್ಠಮ್‌ ತೇ ಜಗತ್‌ ಆಹುಃ ಅನೀಶ್ವರಮ್‌ |\n\nಅಪರಸ್ಪರ ಸಂಭೂತಂ ಕಿಮ್‌ ಅನ್ಯತ್‌ ಕಾಮಹೈತುಕಮ್‌ - ಅವರು ಈ ವಿಶ್ವ ಸತ್ಯ ಸ್ವರೂಪನಾದ ಭಗವಂತನ\nಕೊಡುಗೆಯಲ್ಲ [ಇದೊಂದು ಸುಳ್ಳಿನ ಕಂತೆ] ಎನ್ನುತ್ತಾರೆ. ಇದು ಭಗವಂತನಲ್ಲಿ ನೆಲೆಗೊಂಡದ್ದಲ್ಲ [ಇದಕ್ಕೆ ಇರುವೇ\nಇಲ್ಲ] ಎನ್ನುತ್ತಾರೆ. ಇದನ್ನು ನಿಯಮಿಸುವ ಸರ್ವಶಕ್ತನೊಬ್ಬನಿಲ್ಲ ಎನ್ನುತ್ತಾರೆ. ಒಂದರಿಂದ ಇನ್ನೊಂದು ಕ್ರಮವಾಗಿ\nಹುಟ್ಟಿತು ಎನ್ನುವುದನ್ನೂ ಒಪ್ಪುವುದಿಲ್ಲ. ಮತ್ತೇನು? ಅವರ ದೃಷ್ಟಿಯಲ್ಲಿ ಇದೊಂದು ಬೇರೆಯ ತರ. ಇದೊಂದು\nಕಾಮದ ಕೂಸು-ಮಾಯಾಷಸ್ಕ ಷ್ಟಿ.\n\nಅಸುರರಲ್ಲಿ ಎರಡು ವಿಧ. ಜಗತ್ತಿಗೆ ಇನ್ನೊಂದು ಸತ್ಯವಿಲ್ಲ, ಜಗತ್ತಿಗೆ ಇನ್ನೊಂದು ಪ್ರತಿಷ್ಠೆ ಇಲ್ಲ, ಜಗತ್ತಿಗೆ ಇನ್ನೊಬ್ಬ\nಈಶ್ವರನಿಲ್ಲ ಎನ್ನುವ ನಾಸ್ತಿಕ ತಿಳುವಳಿಕೆ ಇವರಿಗಿರುತ್ತದೆ. ಜಗತ್ತನ್ನು ಸೃಷ್ಟಿ-ಸ್ಥಿತಿ-ಸಂಹಾರಗಳಿಗೆ ಒಳಪಡಿಸುವ\nಶಕ್ತಿ(ಸತ್ಯ) ಇಲ್ಲ ಎಂದು ಇವರು ತಿಳಿದಿರುತ್ತಾರೆ. ಇವರು ಈ ಜಗತ್ತಿಗೆ ಆಧಾರನಾಗಿ ಒಬ್ಬ ದೇವರಿಲ್ಲ, ಆದ್ದರಿಂದ\nಈ ಜಗತ್ತನ್ನು ನಿಯಂತ್ರಿಸುವ ಸ್ವಾಮಿ ಇಲ್ಲ, ಎಲ್ಲವೂ ಭ್ರಮೆ ಎಂದು ವಾದ ಮಾಡುತ್ತಾರೆ. ಸೃಷ್ಟಿಚಕ್ರ ಒಂದು\nಮೂರ್ಬತನದ ಸಿದ್ಧಾಂತ ಎನ್ನುವುದು ಇವರ ನಂಬಿಕೆ.\n\nಇನ್ನೊಂದು ವಿಧದ ಅಸುರರು ಈ ಜಗತ್ತಿನಲ್ಲಿ ನಮಗೆ ಏನು ಕಾಣುತ್ತದೋ ಅದು ಕೇವಲ ನಮ್ಮ ಭ್ರಮೆ ಎಂದು\nಶೂನ್ಯವಾದ ಮಾಡುವವರು. ಇವರು ಈ ಪ್ರಪಂಚ ನಮ್ಮ ಬಯಕೆಗಳಿಂದ ಬೆಳೆಯುತ್ತಿದೆಯೇ ಹೊರತು\nಇನ್ನೊಂದು ಶಕ್ತಿಯಿಂದಲ್ಲ ಎಂದು ನಂಬಿರುತ್ತಾರೆ.\n\nಏತಾಂ ದೃಷ್ಟಿಮವಷ್ಟ ಭ್ಯ ನಷ್ಟಾತ್ಮಾನೋಲ್ಬ ಬುದ್ಧಯಃ |\nಪ್ರಭವಂತ್ಯುಗ್ರಕರ್ಮಾಣಃ ಕ್ಷಯಾಯ ಜಗತೋಹಿತಾಃ ॥1೯॥\n\nಏತಾಮ್‌ ದೃಷ್ಟಿಮ್‌ ಅವಷ್ಟಭ್ಯ ನಷ್ಟ ಆತ್ಮಾನಃ ಅಲ್ಪಬುದ್ಧಯಃ |\nಪ್ರಭವಂತಿ ಉಗ್ರಕರ್ಮಾಣಃ ಕ್ಷಯಾಯ ಜಗತಃ ಅಹಿತಾಃ -ಇಂತಹ ನಿಲುವನ್ನು ನೆಚ್ಚಿಕೊಂಡು ವಿವೇಕ\nಕಳೆದುಕೊಂಡ ಅರಿವುಗೇಡಿಗಳು-ಜನಾಂಗದ ಕೇಡಿಗಳು. ಒರಟು ನಡೆಯ ಇಂತವರು ಜಗದ ನಾಶಕ್ಕೆ\n\nಕಾರಣರಾಗುತ್ತಾರೆ.\n\nಆಸುರ ಮನೋವೃತ್ತಿ ಬೆಳೆಸಿಕೊಳ್ಳುವ ಜನ ತಮ್ಮ ಬದುಕಿಗೆ ಅನರ್ಥವನ್ನು ತಂದುಕೊಂಡು ತಮ್ಮ ನಾಶಕ್ಕೆ\nತಾವೇ ಕಾರಣರಾಗುತ್ತಾರೆ. ಇವರು ತಮ್ಮ ನಂಬಿಕೆಯೇ ತಮ್ಮನ್ನು ನಾಶ ಮಾಡುತ್ತಿದೆ, ತಾವು ಕತ್ತಲೆಯ\nದಾರಿಯಲ್ಲಿ ನಡೆಯುತ್ತಿದ್ದೇವೆ ಎನ್ನುವ ಎಚ್ಚರವೂ ಇಲ್ಲದೆ ಉಗ್ರಗಾಮಿ(ಉಗ್ರಕರ್ಮಾಣಃ)ಗಳಾಗುತ್ತಾರೆ. ಇದರ\nಪರಿಣಾಮ ಇವರು ಲೋಕಶತ್ರುಗಳಾಗಿ, ಲೋಕ ನಾಶಕ್ಕೆ ಕಾರಣರಾಗುತ್ತಾರೆ. ಈ ರೀತಿಯ ಮನೋವೃತ್ತಿ ಇದ್ದು-\nನಮ್ಮ ನಿಮ್ಮ ನಡುವೆ ಇರುವ ಜನರೇ ಅಸುರರು.",
  "16.10": "ಕಾಮಮ್‌ ಆಶ್ರಿತ್ಯ ದುಷ್ಬೂರಂ ಡಂಭ ಮಾನ ಮದ ಅನ್ವಿತಾಃ।\n\nಮೋಹಾತ್‌ ಗೃಹೀತ್ವಾ ಅಸತ್‌ ಗ್ರಾಹಾನ್‌ ಪ್ರವರ್ತಂತೇ ಅಶುಚಿ ವ್ರತಾಃ -ತಣಿಯದ ಬಯಕೆಯ ಬೆನ್ನುಹತ್ತಿ\nಬೂಟಾಟಿಕೆ, ಬಿಂಕ ಮತ್ತು ಸೊಕ್ಕಿಗೆ ತುತ್ತಾದವರು. ಕೊಳಕು ನಡೆಯ ಈ ಮಂದಿ ತಿಳಿಗೇಡಿತನದಿಂದ ತಪ್ಪು\nಗ್ರಹಿಕೆಗಳನ್ನೇ ಕಟ್ಟಿಕೊಂಡು ಬಾಳುತ್ತಾರೆ.\n\nಆಸುರೀ ಸ್ವಭಾವದವರ ಬಯಕೆಗೆ ಕೊನೆ ಇರುವುದಿಲ್ಲ. ಎಷ್ಟು ಬಂದರೂ ಇನ್ನ ಷ್ಟ ರಾಸೆ. ಉದಾಹರಣೆಗೆ ಕೆಲಸವೇ\nಇಲ್ಲದಾಗ ಒಂದು ಕೆಲಸದ ಆಸೆ, ಕೆಲಸ ಸಿಕ್ಕಿದಾಗ ಹೆಚ್ಚು ಸಂಬಳದ ಆಸೆ, ಸಂಬಳ ಬಂದಾಗ ಆ ಸಂಬಳ ತನ್ನ\nಪಕ್ಕದ ಮನೆಯವನಿಗಿಂತ ಕಡಿಮೆ-ಅದಕ್ಕಾಗಿ ಇನ್ನೂ ಹೆಚ್ಚಿನ ಸಂಬಳದ ಆಸೆ, ದೊಡ್ಡ ಹುದ್ದೆಯ ಆಸೆ, ಹೀಗೆ ಎಷ್ಟು\nಸಿಕ್ಕಿದರೂ ತೃಪ್ಪಿ ಇಲ್ಲ. ಈ ದಾಹವನ್ನು ಪೂರೈಸಲು ಸಾಧ್ಯವೇ ಇಲ್ಲ. ಪುರಾಣದಲ್ಲಿ ಹೇಳುವಂತೆ ಹೇಗೆ\nಪಾತಾಳವನ್ನು ಮಣ್ಣುಹಾಕಿ ಮುಚ್ಚಲು ಸಾಧ್ಯವಿಲ್ಲವೋ ಹಾಗೇ ಮನುಷ್ಯನ ಬಯಕೆಯನ್ನು ಪೂರೈಸಲು\nಸಾಧ್ಯವಿಲ್ಲ. ನಮಗೆ ಎಷ್ಟೇ ಹಣ ಸಿಕ್ಕಿದರೂ ಕೂಡಾ ನಾವು ಅದರ ಬಲಬದಿಯಲ್ಲಿ ಒಂದು ಸೊನ್ನೆ\nಸೇರಿಸಿಕೊಂಡು ಕಡಿಮೆಯಾಯಿತು ಎಂದು ಕೊರಗುತ್ತೇವೆ. ಮತ್ತು ಸಂತೋಷವನ್ನು ಮರೆಯುತ್ತೇವೆ.\nಕಠೋಪನಿಷತ್ತಿನಲ್ಲಿ- “ನಿನಗೆ ಎಷ್ಟು ಬೇಕೋ ಅಷ್ಟು ಧನವನ್ನು ಕೊಡುತ್ತೇನೆ” ಎಂದು ಯಮ ಹೇಳಿದಾಗ,\nನಚಿಕೇತ ಹೇಳುತ್ತಾನೆ: “ನ ವಿತ್ತೇನ ತರ್ಪಣೀಯೋ ಮನುಷ್ಯಃ” ಎಂದು. ಅಂದರೆ “ಮನುಷ್ಯನ ಧನದ\n\nಬಯಕೆಯನ್ನು ಪೂರೈಸಲು ಯಾರಿಂದಲೂ ಸಾಧ್ಯವಿಲ್ಲ” ಎಂದು. ಸಾಕು ಎನ್ನುವುದು ದೈವೀ ಸ್ವಭಾವ, ಬೇಕು\nಎನ್ನುವುದು ಆಸುರೀ ಸ್ವಭಾವ. ಹೀಗೆ ಆಸುರೀ ಸ್ವಭಾವದವರು ಬಯಕೆಗಳ ಬೆನ್ನುಹತ್ತಿ, ಆ ತೀರದ ಬಯಕೆಯನ್ನು\nತೀರಿಸಿಕೊಳ್ಳುವುದಕ್ಕೋಸ್ಕರ ಮಾಡಬಾರದ್ದನ್ನು ಮಾಡುತ್ತಾರೆ. ಇವರ ಜೀವನವೇ ಡಂಭಾಚಾರ. ಬಿಗುಮಾನ,\nದುರಹಂಕಾರ, ನಾಟಕೀಯವಾದ ಬದುಕಿನಿಂದ ಇನ್ನೊಬ್ಬರಿಗೆ ಮೋಸ ಮಾಡುವುದು. ಹೀಗೆ ನಡೆ ನುಡಿಯಲ್ಲಿ\nಸ್ವಚ್ಛತೆ ಇಲ್ಲದ ಕೊಳಕು ಬದುಕು ಇವರದ್ದಾಗಿರುತ್ತದೆ.\n",
  "16.11": "ಚಿಂತಾಮ್‌ ಅಪರಿಮೇಯಾಂ ಚ ಪ್ರಳಯಾಂತಾಮ್‌ ಉಪಾಶ್ರಿತಾಃ ।\n\nಕಾಮ ಉಪಭೋಗ ಪರಮಾಃ ಏತಾವತ್‌ ಇತಿ ನಿಶ್ಚಿತಾಃ -- ಸಾವಿನ ಜೊತೆಗೇ ಅಳಿಯುವ, ಅಳೆಯಲಾಗದ\nಚಿಂತೆಗೊಳಗಾದವರು. ಕಾಮದ ತೀಟೆಯೇ ಜೀವನದ ಸರ್ವಸ್ವವಾದವರು. ಜೀವನವೆಂದರೆ ಇಷ್ಟೇ ಎಂದು\nನಂಬಿದವರು.\n\nಇವರ ಕೊರಗಿಗೆ ಕೊನೆಯೇ ಇಲ್ಲ. ಇವರು ತಮ್ಮ ಇಡೀ ಜೀವನವನ್ನು-ಇಲ್ಲದ್ದನ್ನು ಪಡೆಯುವ ಕೊರಗಿನಲ್ಲಿ\nಕಳೆಯುತ್ತಾರೆ. ಇವರು ಚಿಂತೆಯ ದಾಸರಾಗುತ್ತಾರೆ. ಇವರ ಚಿಂತೆ ಪ್ರಳಯಾಂತಕ- ಸಾಯುವ ತನಕವೂ ಅವರ\nಬೆನ್ನುಬಿಡದೆ. ಕಾಡುತ್ತಿರುತ್ತದೆ. ಇವರು. ಭೋಗಜೀವನದ ದಾಸರಾಗಿ, ಅದನ್ನು ಬಿಟ್ಟು ಇರಲಾರದ\nಪರಾಧೀನತೆಯಲ್ಲಿ, ಜೀವನವೆಂದರೆ ಇಷ್ಟೇ ಎಂದು ತಿಳಿದು ಬದುಕುತ್ತಿರುತ್ತಾರೆ.",
  "16.12": "ಆಶಾಪಾಶ ಶತೈಃ ಬದ್ಧಾಃ ಕಾಮಕ್ರೋಧಪರಾಯಹಾಃ।\n\nಈಹಂತೇ ಕಾಮಭೋಗಾರ್ಥ ಅನ್ಯಾಯೇನ ಅರ್ಥಸಂಚಯಾನ್‌ --. ನೂರಾರು ಆಸೆಗಳ ಬಲೆಯಲ್ಲಿ\nಸಿಕ್ಕಿಬಿದ್ದವರು. ಹುಚ್ಚು ಹಂಬಲ-ಸಿಡುಕುಗಳಿಗೆ ತಮ್ಮನ್ನು ಮಾರಿಕೊಂಡವರು. ತೀಟೆ ತೀರಿಸಲೆಂದು ತಪ್ಪು\nದಾರಿಯಿಂದ ರಾಶಿ ರಾಶಿ ಹೊನ್ನು ಬಾಚಬಯಸುವವರು.\n\nಇವರು ಭೋಗದ ಆಸೆಗಾಗಿ ತಮ್ಮನ್ನು ತಾವು ಆಸೆಗಳ ಪಾಶದಲ್ಲಿ ಸಿಲುಕಿ ಹಾಕಿಸಿಕೊಂಡು, ದಿಗೃಂಧನದಿಂದ\nಬದುಕುತ್ತಿರುತ್ತಾರೆ. ಕಾಮ ಕ್ರೋಧಗಳಿಗೆ ತಮ್ಮನ್ನು ಮಾರಿಕೊಂಡು, ಕಾಮಕ್ರೋಧ ಪರಾಯಣರಾಗಿ\nಬದುಕುತ್ತಾರೆ. ಇದಕ್ಕೆ ಉತ್ತಮ ದೃಷ್ಟಾಂತ ಪೌಂಡ್ರಕ ವಾಸುದೇವ. ಆತನಿಗೆ 'ತಾನೇ ದೇವರಾಗಬೇಕು ಎನ್ನುವ\nಕಾಮ'. ಈ ಕಾಮದಿಂದಾಗಿ ಅದು ಸರಿಯಲ್ಲ ಎಂದು ತಿಳಿಹೇಳುವ ತತ್ವಜ್ಞಾನಿಗಳ ಮೇಲೆ ಕೋಪ.\n\nಇವರು ತಮ್ಮ ಸುಖ-ಭೋಗವನ್ನು ತೀರಿಸಿಕೊಳ್ಳಲು ಅನ್ಯಾಯ ಮಾರ್ಗದಲ್ಲಿ ದುಡ್ಡು ಸಂಗ್ರಹ ಮಾಡಲು\nಪ್ರಯತ್ನಿ ಸುತ್ತಿರುತ್ತಾರೆ. ಶಾಸ್ತ್ರದಲ್ಲಿ ಬರೆದಿರುವ ವಿಷಯಗಳನ್ನು ತಮಗೆ ಬೇಕಾದಂತೆ ತಿರುಚಿಕೊಂಡು, ತಮ್ಮ\nಇಷ್ಟಸಿದ್ಧಿ ಸಾಧನೆಯಲ್ಲಿ ತೊಡಗುತ್ತಾರೆ.\n\nಇದಮದ್ಯ ಮಯಾ ಲಬ್ಧಮಿ",
  "16.13": "ಇದಮ್‌ ಅದ್ಯ ಮಯಾ ಲಬ್ಧಮ್‌ ಇಮಮ್‌ ಪ್ರಾಪ್ಸ್ಯೇ ಮನೋರಥಮ್‌ |\nಇದಮ್‌ ಅಸ್ತಿ ಇದಮ್‌ ಅಪಿ ಮೇ ಭವಿಷ್ಯತಿ ಪುನರ್ಧನಮ್‌ -- ಇದನ್ನೀಗ ನಾನು ಪಡೆದೆ; ಈ ಬಯಕೆಯನ್ನು ಮುಂದೆ ಈಡೇರಿಸಿಕೊಳ್ಳುತ್ತೇನೆ; ಇದಂತೂ ಇದೆ; ಮತ್ತೆ ಈ ಹೊನ್ನೂ ನನ್ನದಾಗಲಿದೆ;\n\nಆಸುರೀ ಸ್ವಭಾವದವರ ಯೋಚನೆಗಳು ಹೇಗಿರುತ್ತವೆ ಎಂದರೆ — ಸದಾ ಧನ ಸಂಗ್ರಹ ಮಾಡಬೇಕು ಎನ್ನುವ ಯೋಚನೆ. ಸಿಕ್ಕಿದಾಗ “ಇಂದು ಇಷ್ಟು ಸಿಕ್ಕಿತು, ನಾಳೆ ಇಷ್ಟು ಗಳಿಸುತ್ತೇನೆ\" ಎನ್ನುವ ಸಂಗ್ರಹವೃತ್ತಿ.",
  "16.14": "ಅಸೌ ಮಯಾ ಹತಃ ಶತ್ರುಃ ಹನಿಷ್ಯೇ ಚ ಅಪ ರಾನ್‌ ಅಪಿ |\nಈಶ್ವರಃ ಅಹಮ್‌ ಅಹಮ್‌ ಭೋಗೀ ಸಿದ್ಧಃ ಅಹಂ ಬಲವಾನ್‌ ಸುಖೀ -- ಈ ಹಗೆಯನ್ನು ಕೊಂದೆ; ಉಳಿದವರನ್ನೂ ಮುಗಿಸಲಿದ್ದೇನೆ; ನಾನು ಸರ್ವಶಕ್ತ; ನಾನೇ ಭೋಗಿಸುವವನು; ನಾನೇ ಬಯಸಿದ್ದನ್ನೆಲ್ಲಾ ಪಡೆದವನು; ಶಕ್ತಿಶಾಲಿ ಮತ್ತು ಸುಖಿ;\n\nಆಸುರೀ ಸ್ವಭಾವದವರ ಅಹಂಕಾರದ ಚಿತ್ರ — ತಾನೇ ಸರ್ವಶಕ್ತ ಎಂದು ನಂಬುವುದು. \"ನಾನೇ ಈಶ್ವರ\", \"ನಾನೇ ಭೋಗಿ\" ಎನ್ನುವ ಈ ಅಹಂಕಾರವೇ ಅವರ ಪತನದ ಮೂಲ.",
  "16.15": "ಆಢ್ಯೋ ಅಭಿಜನವಾನ್‌ ಅಸ್ಮಿ ಕಃ ಅನ್ಯಃ ಅಸ್ತಿ ಸದೃಶಃ ಮಯಾ |\nಯಕ್ಷ್ಯೇ ದಾಸ್ಯಾಮಿ ಮೋದಿಷ್ಯೇ ಇತಿ ಅಜ್ಞಾನ ವಿಮೋಹಿತಾಃ -- ಅವರು ತಿಳಿಗೇಡಿತನದಿಂದ ಹೀಗೆ ಬಡಬಡಿಸುತ್ತಾರೆ: ಪಿರಿವಂತನಿದ್ದೇನೆ; ಕುಲವಂತನಿದ್ದೇನೆ; ಯಾರಿದ್ದಾರೆ ನನಗೆ ಸಾಟಿ? ನಾನು ಯಾಗ ಮಾಡಿಸುತ್ತೇನೆ. ದಾನ ನೀಡುತ್ತೇನೆ. ಖುಶಿಪಡುತ್ತೇನೆ.\n\nಆಸುರೀ ಸ್ವಭಾವದವರ ಯೋಚನೆಗಳು ಹೇಗಿರುತ್ತವೆ ಎನ್ನುವುದನ್ನು ಕೃಷ್ಣ ಈ ಮೂರು ಶ್ಲೋಕದಲ್ಲಿ\nವಿವರಿಸಿದ್ದಾನೆ. ಇವರಿಗೆ ಸದಾ ಧನ ಸಂಗ್ರಹ ಮಾಡಬೇಕು ಎನ್ನುವ ಯೋಚನೆ. ಸಿಕ್ಕಿದಾಗ “ಇಂದು ಇಷ್ಟು\nಸಿಕ್ಕಿತು, ನಾಳೆ ಇಷ್ಟು ಗಳಿಸುತ್ತೇನೆ' ಎನ್ನುವ ಚಪಲ. ದುಡ್ಡು ಸಂಗ್ರಹ ಮಾಡುವುದು ಇವರಿಗೊಂದು ಚಟ. ತನಗೆ\nಆಗದವನನ್ನು ಮುಗಿಸಿದೆ, ಇನ್ನು ಆಗದವರನ್ನು ಮುಗಿಸುವೆ ಎನ್ನುವ ಯೋಚನೆ. ನಾನೇ ಸರ್ವ ಸಮರ್ಥ,\nನನ್ನಿಂದಾಗದ್ದು ಈ ಜಗತ್ತಿನಲ್ಲೇನಿದೆ? ನಾನು ಸುಖ ಪಡಲು ಹುಟ್ಟಿದವನು-ದುಃಖಪಡಲಿಕ್ಕಲ್ಲ; ನನ್ನ ಸುಖಕ್ಕಾಗಿ\nಏನು ಬೇಕಾದರೂ ನಾನು ಮಾಡುತ್ತೇನೆ; ಅದಕ್ಕೆ ಅಡ್ಡ ಬರುವವರನ್ನು ಮುಗಿಸುತ್ತೇನೆ; ನಾನೇ ಸಿದ್ಧ ಪುರುಷ;\n\nನನ್ನ ಸಿದ್ದಿಗೆ ನಾನೇ ಹೊಣೆಗಾರ; ನಾನು ಸುಖಪಡಲು ಹುಟ್ಟಿದವ ಅದಕ್ಕೆ ಬೇಕಾದ ಜನ-ಧನ-ಅಧಿಕಾರ\nನನ್ನಲ್ಲಿದೆ; ನನ್ನಿಚ್ಛೆಯಂತೆ. ನಾನು ನಡೆದುಕೊಳ್ಳುತ್ತೇನೆ; ದುಡ್ಡಿನಿಂದ ಏನನ್ನಾದರೂ ಖರೀದಿಸಬಲ್ಲೆ; ನನಗೆ\nಸರಿಸಾಟಿ. ಈ ಜಗತ್ತಿನಲ್ಲಿ ಯಾರಿದ್ದಾರೆ? - ಇತ್ಯಾದಿ ಇವರ ಯೋಚನೆಗಳು. ತೋರಿಕೆಗಾಗಿ ಯಜ್ಞ\nಯಾಗಾದಿಗಳನ್ನು ಮಾಡುವುದು, ದಾನ ನೀಡುವುದು ಇವರ ನಿರಂತರ ಚಟುವಟಿಕೆ. ಇದು ಅಜ್ಞಾನದ ನಾಟ್ಯ.\nಇದು ಅವರ ಸರ್ವನಾಶದ ಹೆಬ್ಬಾಗಿಲು ಎನ್ನು ವ ಪರಿವೇ ಅವರಿಗಿರುವುದಿಲ್ಲ. ಅದೇ ದೊಡ್ಡಸ್ತಿಕೆ, ಅದೇ ಸುಭಗತನ\n\nಎನ್ನುವ ಭ್ರಮೆಯಲ್ಲಿ ಇವರು ಬದುಕುತ್ತಿರುತ್ತಾರೆ.\n",
  "16.16": "ಅನೇಕ ಚಿತ್ತ ವಿಭ್ರಾಂತಾಃ ಮೋಹಜಾಲ ಸಮಾವೃತಾಃ ।\n\nಪ್ರಸಕ್ತಾಃ ಕಾಮಭೋಗೇಷು ಪತನ್ನಿ. ನರಕೇ ಅಶುಚೌ್‌ -ಹಲವು. ಬಗೆಯ ಯೋಚನೆಗಳಿಂದ\nಗೊಂದಲಗೊಂಡವರು; ಮೋಹದ ಬಲೆಯಲ್ಲಿ ಸಿಕ್ಕಿಕೊಂಡವರು; ಕಾಮದ ತೀಟೆಗಳಲ್ಲಿ ಮೈಮರೆತವರು. ಅವರು\nಕೊಳಕು ನರಕದಲ್ಲಿ ಬಿದ್ದು ನರಳುತ್ತಾರೆ.\n\nಇವರು ತಮ್ಮ ಜೀವನದಲ್ಲಿ ಹಿಂದೆ ಆಗಿಹೋದ ಘಟನೆಗಳನ್ನು ಸದಾ ನೆನಪಿಸಿಕೊಂಡು ಗೊಂದಲಗೊಳ್ಳುತ್ತಾರೆ.\nಇವರು. ಎಂದೂ ತಮ್ಮ ತಪ್ಪಿಗೆ ಪಶ್ಚಾತ್ತಾಪ ಪಡುವುದಿಲ್ಲ. ಸಾತ್ವಿಕರು ಪಶ್ಚಾತ್ತಾಪ ಪಟ್ಟು ತಪ್ಪನ್ನು\nಸರಿಪಡಿಸಿಕೊಳ್ಳುತ್ತಾರೆ, ಆದರೆ. ಇವರು ಸದಾ ಭಯಂಕರವಾದ ಅಜ್ಞಾನ-ಮಮಕಾರವೆಂಬ ಮೋಹದ\nಬಲೆಯಲ್ಲಿ ಸಿಕ್ಕಿಹಾಕಿಕೊಂಡು ಮತ್ತಷ್ಟು ಗೊಂದಲಕ್ಕೊಳಗಾಗುತ್ತಾರೆ-ತಿದ್ದಿಕೊಳ್ಳುವುದಿಲ್ಲ. ತಾವು ಬಯಸಿದ\nವಸ್ತುವನ್ನು ಭೋಗಿಸುವುದು ಮತ್ತು ಅದರಲ್ಲಿ ತೃಪ್ತಿಪಡದೆ ಮತ್ತಷ್ಟು ಸಂಗ್ರಹಮಾಡಿ ಜೋಪಾನ ಮಾಡುವುದರಲ್ಲಿ\nಪ್ರವೃತ್ತರಾಗುತ್ತಾರೆ. ಇವರು ಮುಂದೆ ಕೊಳಕು ನರಕದಲ್ಲಿ ಬಿದ್ದು ಒದ್ದಾಡಬೇಕಾಗುತ್ತದೆ.\n",
  "16.17": "ಆತ್ಮಸಂಭಾವಿತಾಃ ಸ್ವಬ್ಧಾಃ ಧನ ಮಾನಮ್‌ ಮದ ಅನ್ವಿತಾಃ |\n\nಯಜಂತೇ ನಾಮಯಜ್ಜ್ಞ್ಯೈಃ ತೇ ಡಂಭೇನ ಅವಿಧಿ ಪೂರ್ವಕಮ್‌ -ತಮ್ಮ ಬಗೆಗೇ ಕೊಚ್ಚಿಕೊಳ್ಳುವವರು. ಸಿರಿ\nಸಮ್ಮಾನದ ಸೊಕ್ಕಿನಿಂದ ಬೀಗಿದವರು. ಅಂತವರೂ ಯಜ್ಞಗಳನ್ನಾಚರಿಸುತ್ತಾರೆ: ಬೂಟಾಟಿಕೆಯಿಂದ, ಶಾಸ್ತ್ರದ\nಕಟ್ಟಳೆಯ ಕಟ್ಟು ಮುರಿದು.\n\nತಮ್ಮ ಬಗ್ಗೆ ತಮಗೇ ಹೆಗ್ಗಳಿಕೆ ಇವರಿಗೆ. “ಅವಿದ್ಯಾಯಾಂ ಅಂತರೇ ವರ್ತಮಾನಾಃ ಸ್ವಯಂ ಧೀರಾ ಪಂಡಿತಂ\nಅನ್ಯಮಾನಾ” ಎನ್ನು ವಂತೆ ಉಳಿದವರಿಗೆ ತಮ್ಮ ಮೇಲೆ ಗೌರವ ಇದೆಯೊ ಇಲ್ಲವೋ ಗೊತ್ತಿಲ್ಲ, ಆದರೆ ತನ್ನ ಬಗ್ಗೆ\n\nತಾನೇ ಮಹತ್ವ ಜ್ಞಾನ ಬೆಳಸಿಕೊಂಡು ಅದರಿಂದ ಬಿಗುಮಾನದಿಂದ ಬೀಗುತ್ತಿರುತ್ತಾರೆ. ಇವರ ಈ ಬಿಗುಮಾನಕ್ಕೆ\nಕಾರಣ ಜ್ಞಾನವಲ್ಲ, ಬದಲಿಗೆ ಕೈಯಲ್ಲಿರುವ ದುಡ್ಡಿನ ಮದ; ಆ ದುಡ್ಡಿಗೋಸ್ಕರ ಜನ ಮಾಡುವ ಸಮ್ಮಾನ. ಇವರು\nಬೂಟಾಟಿಕೆಗಾಗಿ, ದೊಡ್ಡಸ್ತಿಕೆಯ ಪ್ರದರ್ಶನಕ್ಕಾಗಿ-ಯಜ್ಞ ಯಾಗಾದಿಗಳನ್ನು ಮಾಡಿಸುತ್ತಾರೆ. ಅಲ್ಲಿ ಶಾಸ್ತ್ರದ\nಎಚ್ಚರವಿರುವುದಿಲ್ಲ; ಭಗವಂತ ಪ್ರೀತನಾಗಲಿ ಎನ್ನುವ ಉದ್ದೇಶವಿಲ್ಲದ, ಅಂತರ್ಯಾಮಿ ಭಗವಂತನನ್ನು ಮರೆತು\nಮಾಡುವ ಪೂಜೆ ಅದಾಗಿರುತ್ತದೆ.",
  "16.18": "ಅಹಂಕಾರಂ ಬಲಂ ದರ್ಪಂ ಕಾಮಂ ಕ್ರೋಧಂ ಚ ಸಂಶ್ರಿತಾಃ ।\nಮಾಮ್ ಆತ್ಮ ಪರದೇಹೇಷು ಪ್ರದ್ವಿಷಂತಃ ಅಭ್ಯಸೂಯಕಾಃ -- ಹಮ್ಮು, ಬಲತ್ಕಾರ, ಸೊಕ್ಕು, ಬಯಕೆ, ಸಿಡುಕುಗಳ ನೆಲೆಯಾದವರು. ತನ್ನ ಮತ್ತು ಪರರ ದೇಹದೊಳಗಿರುವ ನನ್ನನ್ನು ನಂಬದೇ ನಿರಾಕರಿಸುವವರು. ಇನ್ನೊಬ್ಬರ ಏಳಿಗೆಗೆ ಕಿಚ್ಚುಪಡುವವರು.\n\nಇವರ ಮೂಲ ಆಸ್ತಿ - ಅಹಂಕಾರ, ದರ್ಪ, ಕಾಮ ಮತ್ತು ಕ್ರೋಧ. ನನ್ನನ್ನು ಮೀರಿಸುವವರು ಯಾರಿದ್ದಾರೆ? ನಾನೇ ದೊಡ್ಡ ಮನುಷ್ಯ ಎನ್ನುವ ಅಹಂಕಾರ. ಅದಕ್ಕೆ ಬೆಂಬಲ ಧನ ಮತ್ತು ಅಧಿಕಾರ ಬಲ. ಇದರಿಂದ ಇನ್ನೊಬ್ಬರನ್ನು ತಿರಸ್ಕಾರದಿಂದ ಕಾಣುವ ದರ್ಪ. ತೀರದ ಬಯಕೆಗಳು, ಅವು ಈಡೇರದಿಲ್ಲ ಎನ್ನುವ ಕೋಪ - ಇದೇ ಅವರ ಅಸ್ತಿತ್ವ. ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: \"ಎಲ್ಲರೊಳಗಿರುವ 'ನನ್ನನ್ನು' ನಂಬದೇ ನಿರಾಕರಿಸುತ್ತಾರೆ\" ಎಂದು. ಇದು ಯಾವುದೋ ಕಾರಣನಿಮಿತ್ತ ತಾತ್ಕಾಲಿಕವಾಗಿ ಭಗವಂತನನ್ನು ನಿರಾಕರಿಸುವುದಲ್ಲ, ಬದಲಿಗೆ ಸ್ವರೂಪತಃ ಭಗವಂತನನ್ನು ನಿರಾಕರಿಸುವುದು. ಇಂತವರು ಇನ್ನೊಬ್ಬರ ಜ್ಞಾನ ಮತ್ತು ಧನ ಸಂಪತ್ತನ್ನು ನೋಡಿ ಸದಾ ಅಸೂಯೆ ಪಡುತ್ತಿರುತ್ತಾರೆ.",
  "16.19": "ಏತಾಮ್‌ ದೃಷ್ಟಿಮ್‌ ಅವಷ್ಟಭ್ಯ ನಷ್ಟ ಆತ್ಮಾನಃ ಅಲ್ಪಬುದ್ಧಯಃ |\nಪ್ರಭವಂತಿ ಉಗ್ರಕರ್ಮಾಣಃ ಕ್ಷಯಾಯ ಜಗತಃ ಅಹಿತಾಃ -ಇಂತಹ ನಿಲುವನ್ನು ನೆಚ್ಚಿಕೊಂಡು ವಿವೇಕ\nಕಳೆದುಕೊಂಡ ಅರಿವುಗೇಡಿಗಳು-ಜನಾಂಗದ ಕೇಡಿಗಳು. ಒರಟು ನಡೆಯ ಇಂತವರು ಜಗದ ನಾಶಕ್ಕೆ\n\nಕಾರಣರಾಗುತ್ತಾರೆ.\n\nಆಸುರ ಮನೋವೃತ್ತಿ ಬೆಳೆಸಿಕೊಳ್ಳುವ ಜನ ತಮ್ಮ ಬದುಕಿಗೆ ಅನರ್ಥವನ್ನು ತಂದುಕೊಂಡು ತಮ್ಮ ನಾಶಕ್ಕೆ\nತಾವೇ ಕಾರಣರಾಗುತ್ತಾರೆ. ಇವರು ತಮ್ಮ ನಂಬಿಕೆಯೇ ತಮ್ಮನ್ನು ನಾಶ ಮಾಡುತ್ತಿದೆ, ತಾವು ಕತ್ತಲೆಯ\nದಾರಿಯಲ್ಲಿ ನಡೆಯುತ್ತಿದ್ದೇವೆ ಎನ್ನುವ ಎಚ್ಚರವೂ ಇಲ್ಲದೆ ಉಗ್ರಗಾಮಿ(ಉಗ್ರಕರ್ಮಾಣಃ)ಗಳಾಗುತ್ತಾರೆ. ಇದರ\nಪರಿಣಾಮ ಇವರು ಲೋಕಶತ್ರುಗಳಾಗಿ, ಲೋಕ ನಾಶಕ್ಕೆ ಕಾರಣರಾಗುತ್ತಾರೆ. ಈ ರೀತಿಯ ಮನೋವೃತ್ತಿ ಇದ್ದು-\nನಮ್ಮ ನಿಮ್ಮ ನಡುವೆ ಇರುವ ಜನರೇ ಅಸುರರು.",
  "16.20": "ಆಸುರೀಂ ಯೋನಿಮ್‌ ಆಪನ್ನಾಃ ಮೂಢಾಃ ಜನ್ಮನಿಜನ್ಮನಿ |\nಮಾಮ್‌ ಅಪ್ರಾಪ್ಯ ಏವ ಕೌಂತೇಯ ತತಃ ಯಾಂತಿ ಅಧಮಾಂ ಗತಿಮ್‌-ಕೌಂತೇಯಾ, ಕೆಡುನಡೆಯ\nಬಸಿರಿನಲ್ಲಿ ಮರಳಿಮರಳಿ ಹುಟ್ಟಿಬಂದ ಆ ತಿಳಿಗೇಡಿಗಳು ಕೊನೆಗೂ ನನ್ನನ್ನು ಸೇರದೆಯೇ, ಅಲ್ಲಿಂದ ಮತ್ತೆ\n\nಅಧೋಗತಿಯನ್ನು ಪಡೆಯುತ್ತಾರೆ.\n\nಈ ರೀತಿ ಹೀನ ಮನೆತನದಲ್ಲಿ ಮರಳಿಮರಳಿ ಹುಟ್ಟಿ ಬರುವ ಈ ದುಷ್ಟರು ಪ್ರತೀ ಜನ್ಮದಲ್ಲೂ ಮೂಢರಾಗುತ್ತಾ\nಹೋಗುತ್ತಾರೆ. ಪ್ರತೀ ಜನ್ಮದಲ್ಲೂ ಇವರ ಭಗವಂತನ ಮೇಲಿನ ದ್ವೇಷ ಪರಾಕಾಷ್ಠೆಗೆ ಹೋಗುತ್ತದೆ. ಅಹಂಕಾರ,\nಮದ, ದರ್ಪ, ಕಾಮ ಕ್ರೋಧ ಮಿತಿಮೀರಿ ಇವರು ತಾವಾಗಿಯೇ ಅಧಃಪಾತವನ್ನು ಹೊಂದುತ್ತಾರೆ. ಇವರೆಂದೂ\nಭಗವಂತನನ್ನು ಸೇರುವುದಿಲ್ಲ. ಇವರು ತಮ್ಮ ಜೀವಸ್ವಭಾವದ ಗತಿಗನುಗುಣವಾಗಿ ತಾಮಸಲೋಕವನ್ನು\n\nಸೇರುತ್ತಾರೆ.\n\nಆಸುರೀ ಜನರ ಜೀವ ಸ್ವಭಾವ, ಅವರ ನಡೆ-ನುಡಿ-ಯೋಚನೆ-ಕೃತಿಯ ಬಗ್ಗೆ ಸುಂದರವಾಗಿ ಕೃಷ್ಣ ವಿವರಿಸಿದ.\nಇದರಿಂದ ನಮಗೆ ಲೋಕದಲ್ಲಿ ಲೋಕಕಂಟಕರು ಏಕಿದ್ದಾರೆ? ಅವರು ಮುಂದೆ ಯಾವ ಗತಿಯನ್ನು ಪಡೆಯುತ್ತಾರೆ\nಎನ್ನುವ ವಿಚಾರ ತಿಳಿಯುತ್ತದೆ. ನಮಗರಿವಿಲ್ಲದೆ ನಮ್ಮನ್ನು ಆಸುರೀ ಗುಣ ಕಾಡಿದಾಗ ನಾವು ಜ್ಞಾನದ\nಅರಿವಿನಿಂದ ಭಗವಂತನಲ್ಲಿ ಮೊರೆ ಹೊಕ್ಕು, ಅದರಿಂದ ಬಿಡುಗಡೆಗೆ ಇಚ್ಚಿಸಲು ಈ ಅಧ್ಯಾಯ ಸಹಕರಿಸುತ್ತದೆ.\nಜೀವದ ಸ್ವಭಾವ ಎಂದೂ ಬದಲಾಗುವುದಿಲ್ಲ. ಜೀವಕ್ಕೆ ಸ್ವತಂತ್ರ ಕರ್ತೃತ್ವ ಇಲ್ಲ. ಆದರೆ ಜೀವಕ್ಕೆ ಇಚ್ಛಾಪೂರ್ವಕ\nಕೃತಿ ಇದೆ. ಇದಕ್ಕನುಗುಣವಾಗಿ ನಿರಂತರ ದೈವೀ ಸ್ವಭಾವವನ್ನು ಬೆಳಸಿಕೊಂಡು-ಭಗವಂತನನ್ನು ಸೇರುವ\nಪ್ರಯತ್ನವನ್ನು ನಾವು ಮಾಡಬೇಕು. ಅದಕ್ಕೆ ಫಲ ಸಿಗುವುದು ಬಿಡುವುದು ಭಗವಂತನ ಇಜ್ಜೆ-ಅದಕ್ಕಾಗಿ ನಾವು\nತಲೆಕೆಡಿಸಿಕೊಳ್ಳಬಾರದು. ಒಳ್ಳೆಯದನ್ನು ಇಚ್ಚಿಸು, ಒಳ್ಳೆಯವನಾಗಿ ಇದ್ದದ್ದರಲ್ಲಿ ತೃಪ್ತಿಪಟ್ಟು ಬದುಕು. ನಿನ್ನ\nರಕ್ಷಣೆಯ ಭಾರ ಭಗವಂತನದು, ಆತ ನಿನ್ನನ್ನು ರಕ್ಷಿಸಿಯೇ ರಕ್ಷಿಸುತ್ತಾನೆ.\n",
  "16.21": "ತ್ರಿವಿಧಂ ನರಕಸ್ಯ ಇದಂ ದ್ವಾರಂ ನಾಶನಮ್‌ ಆತ್ಮನಃ |\nಕಾಮಃ ಕ್ರೋಧಃ ತಥಾ ಲೋಭಃ ತಸ್ಮಾತ್‌ ಏತತ್‌ ತ್ರಯಮ್‌ ತ್ಯಜೇತ್‌ - ಇವು ಮೂರು ಆತ್ಮ ನಾಶದ ದಾರಿ,\nನರಕದ ಬಾಗಿಲು: ಕಾಮ, ಕ್ರೋಧ, ಮತ್ತು ಲೋಭ. ಆದ್ದರಿಂದ ಈ ಮೂರನ್ನು ದೂರವಿಡಬೇಕು.\n\nಈ ಶ್ಲೋಖ ಬಹಳ ಮುಖ್ಯವಾದ ಸಂದೇಶವನ್ನು ಕೊಡುವ ಶ್ಲೋಕ. ವಿದುರನೀತಿಯಲ್ಲಿ ಕೂಡಾ ಈ ಶ್ಲೋಕ\nಬಂದಿದೆ. ಸಾಮಾಜಿಕ ಮತ್ತು ಆಧ್ಯಾತ್ಮಿಕ ನಿಟ್ಟಿನಲ್ಲಿ ಮಹಾಭಾರತ ಇದನ್ನು ಉಲ್ಲೇಖಮಾಡುತ್ತದೆ. ಇಲ್ಲಿ ಕೃಷ್ಣ\nಆತ್ಮನಾಶಕ್ಕೆ ಕಾರಣವಾಗುವ ಮೂರು ಅಂಶಗಳನ್ನು ವಿವರಿಸಿದ್ದಾನೆ. ಅವುಗಳೆಂದರೆ ಕಾಮ-ಕ್ರೋಧ-ಲೋಭ.\nಇವು \"ಮಾನವನ ನರಕದ ಬಾಗಿಲು” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಕ್ರೋಧ ಎನ್ನುವುದು ಕಾಮದ ಮರಿ. ನಮಗೆ ಕ್ರೋಧ\nಬರುತ್ತಿದೆ ಎಂದರೆ ನಮ್ಮ ಒಳಗೆ ಬಹಳ ಆಸೆಗಳು ಹುದುಗಿವೆ ಎಂದರ್ಥ. ಅದು ನೆರವೇರದೇ ಇದ್ದಾಗ ನಮಗೆ\nಕೋಪ. ಮಹಾಭಾರತದ ಅನುಶಾಸನ ಪರ್ವದಲ್ಲಿ ಒಂದು ಕಥೆ ಇದೆ. ಓರ್ವ ಬ್ರಾಹ್ಮಣ ಸ್ತ್ರೀ; ಆಕೆಯ ಹೆಸರು\nಗೌತಮಿ. ಆಕೆಗೆ ಒಬ್ಬನೇ ಮಗ. ಒಂದು ದಿನ ಹಾವು ಕಚ್ಚೆ ಆತ ಸಾಯುತ್ತಾನೆ. ಇದನ್ನು ಒಬ್ಬ ಹಾವಾಡಿಗ ಕಂಡು,\nಕೂಡಾಲೇ ಆ ಹಾವನ್ನು ಹಿಡಿದು ಆಕೆಯ ಎದುರು ತಂದು: “ಹೇಳು, ನಿನ್ನ ಮಗನನ್ನು ಕಚ್ಚಿ ಕೊಂದ ಈ ಹಾವನ್ನು\nಯಾವ ರೀತಿ ಕೊಲ್ಲಲು ನೀನು ಇಷ್ಟ ಪಡುತ್ತೀಯ” ಎಂದು ಕೇಳುತ್ತಾನೆ. ಆಗ ಆಕೆ ಹೇಳುತ್ತಾಳೆ: “ನ\nಬ್ರಾಹ್ಮಣಾನಂ ಕೋಪೋಇಸತಿ ಕೃತಃ ಕೋಪಾಚ ಚ ಯಾತನಾ...” ೧೩-೦೧-೨೦|. “ನಾವು ಬ್ರಾಹ್ಮಣರು,\nಬ್ರಾಹ್ಮಣನಿಗೆ ಕೋಪ ಬರುವುದಿಲ್ಲ, ಬಂದರೆ ಆತ ಬ್ರಾಹ್ಮಣನೇ ಅಲ್ಲ” ಎಂದು. ಹಾವನ್ನು ಕೊಲ್ಲುವುದರಿಂದ, ಸತ್ತ\nಮಗ ಮರಳಿ ಬದುಕಲಾರ. ನನ್ನ ಮಗ ಆತನ ಕರ್ಮಕ್ಕನುಗುಣವಾಗಿ ಸತ್ತ. ಅದಕ್ಕಾಗಿ ಕೋಪ ದುಃಖ ತರವಲ್ಲ,\nಬಿಟ್ಟುಬಿಡು ಆ ಹಾವನ್ನು” ಎನ್ನು ತಾಳೆ ಆಕೆ. ಯಾರಿಗೆ ತಿಳುವಳಿಕೆ ಇದೇ, ಬಯಕೆಗಳಿಲ್ಲಾ -ಅಂತವರಿಗೆ ಕೋಪ\nಬರುವುದಿಲ್ಲ. ಅವರು ನಿಜವಾದ ಬ್ರಾಹ್ಮಣ ಎನಿಸುತ್ತಾರೆ. “ಕಾಮ-ಕ್ರೋಧ-ಲೋಭ ಎನ್ನು ವುದು ನಮ್ಮನ್ನು\nಅಧಃಪಾತಕ್ಕೆ ತಳ್ಳುವ ಮೂರು ನರಕದ ಬಾಗಿಲುಗಳು, ಅವುಗಳಿಂದ ದೂರವಿರು” ಎಂದು ಕೃಷ್ಣ ಇಲ್ಲಿ ನಮ್ಮನ್ನು\nಎಚ್ಚರಿಸಿದ್ದಾನೆ. ಇವು ನಮ್ಮ ವ್ಯಕ್ತಿತ್ವವನ್ನು ಹಾಳುಮಾಡುವ ಮೂಲ ಶತ್ರುಗಳು. ಇತರ ಎಲ್ಲಾ ದುರ್ಗುಣಗಳೂ\nಇವುಗಳ ಮರಿಗಳು. ಮನುಷ್ಯ ಈ ಮೂರು ದುರ್ಗುಣಗಳಿಂದ ತನ್ನ ನರಕವನ್ನು ತಾನೇ ಸೃಷ್ಟಿಸಿಕೊಳ್ಳುತ್ತಾನೆ. ಈ\n\nಮೂರನ್ನು ಬಿಟ್ಟರೆ ಇಹದಲ್ಲೂ ಸುಖ-ಪರದಲ್ಲೂ ಸುಖ.\n",
  "16.22": "ಏತೈಃ ವಿಮುಕ್ತಃ ಕೌಂತೇಯ ತಮಃ ದ್ವಾರೈಃ ತ್ರಿಬಿಃ ನರಃ ।\n\nಆಚರತಿ ಆತ್ಮನಃ ಶ್ರೇಯಃ ತತಃ ಯಾತಿ ಪರಾಂ ಗತಿಮ್‌ -. ಕೌಂತೇಯಾ, ನರಕದ ಈ ಮೂರು\nಬಾಗಿಲುಗಳಿಂದ ಪಾರಾದ ನರನು ತನಗೆ ಒಳಿತಾದ್ದನ್ನು ಮಾಡಬಲ್ಲವನಾಗುತ್ತಾನೆ. ಅದರಿಂದ\nಉತ್ತಮಗತಿಯನ್ನೂ ಪಡೆಯುತ್ತಾನೆ.\n\nನರಕದ ಈ ಮೂರು ಬಾಗಿಲುಗಳಿಂದ ಪಾರಾದ ಮಾನವ ಪುಣ್ಯಾತ್ಮ. ಆತನಿಗೆ ಮೋಕ್ಷದ ದಾರಿ\nಸುಗಮವಾಗುತ್ತದೆ. ಆತ ಉತ್ತಮ ಗತಿಯನ್ನು ಪಡೆಯುತ್ತಾನೆ. ಇಲ್ಲಿ ಕೃಷ್ಣ 'ವಿಮುಕ್ತ' ಎನ್ನುವ ಪದವನ್ನು\nಬಳಸಿದ್ದಾನೆ. ಇದರ ಅರ್ಥ ಎಲ್ಲಾ ಕಾಮನೆಗಳನ್ನೂ ಬಿಡುವುದಲ್ಲ, ನಮ್ಮ ಬದುಕಿಗೆ ಭಾದಕವಾಗಿರುವ ರಾಜಸ\nಮತ್ತು ತಾಮಸ ಕಾಮನೆಗಳನ್ನು ಬಿಡುವುದು ಎಂದರ್ಥ. ಉದಾಹರಣೆಗೆ ಭಗವಂತನನ್ನು ಸೇರಬೇಕು\nಎನ್ನುವುದೂ ಒಂದು ಕಾಮನೆ. ಇದು ನರಕದ ಬಾಗಿಲಲ್ಲ. ಇದನ್ನು ಬಿಡಬೇಕಾಗಿಲ್ಲ. ಕಾಮ ಇಲ್ಲದೇ ಜೀವನವಿಲ್ಲ.\nಆದ್ದರಿಂದ ಇಲ್ಲಿ ನಾವು ಬಿಡಬೇಕಾಗಿರುವುದು ಕೇವಲ ರಾಜಸ ಮತ್ತು ತಾಮಸ ಅಂಶವನ್ನು. ಇದನ್ನು\nಸೂಚಿಸುವುದಕ್ಕಾಗಿ ಇಲ್ಲಿ ಮುಕ್ತ' ಎಂದು ಹೇಳದೇ 'ವಿ-ಮುಕ್ತ' ಎಂದು ಹೇಳಲಾಗಿದೆ.\n\nಇಲ್ಲಿ 'ಕೌಂತೇಯ' ಎನ್ನುವ ವಿಶೇಷಣ ಬಳಕೆಯಾಗಿದೆ. “ನಾವು ಜ್ಞಾನ ಮಾರ್ಗದಲ್ಲಿ ಸಾಗಬೇಕಾದರೆ\nಕುತ್ಸಿತವಾದ ಈ ಕಾಮ-ಕ್ರೋಧ-ಲೋಭವನ್ನು ತಿರಸ್ಕಾರ ಮಾಡುವ ಕೌಂತೇಯರಾಗಬೇಕು' ಎನ್ನುವ ಸಂದೇಶ\nಈ ವಿಶೇಷಣದ ಹಿಂದಿರುವ ಧ್ವನಿ.\n\nನಮ್ಮಲ್ಲಿ ಕೆಲವರಿಗೆ ಶಾಸ್ತ್ರದ ವಿಧಿ ವಿಧಾನ ಏಕೆ ಬೇಕು, ಆತ್ಮ ಸಾಕ್ಷಿಯಿಂದ ಬದುಕಿದರೆ ಸಾಲದೇ? ಎನ್ನುವ ಪ್ರಶ್ನೆ\nಇದೆ. ಕೃಷ್ಣ ಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ಶಾಸ್ತ್ರದ ವಿಧಿ-ವಿಧಾನ ಪಾಲನೆಯ ಮಹತ್ವವನ್ನು ವಿವರಿಸುತ್ತಾನೆ.\n",
  "16.23": "ಯಃ ಶಾಸ್ತ್ರವಿಧಿಮ್‌ ಉತ್ಸ ಜ್ಯ ವರ್ತತೇ ಕಾಮಕಾರತಃ |\nನಸಃ ಸಿದ್ಧಿಮ್‌ ಅವಾಪ್ನೊ ತಿ ನ ಸುಖಂನ ಪರಾಂ ಗತಿಮ್‌ -ಶಾಸ್ತ್ರದ ಕಟ್ಟ ಳೆಯನ್ನು ಮೀರಿ ಇಷ್ಟಬಂದಂತೆ\nನಡೆವವನು ಸಿದ್ಧಿಯನ್ನು ಪಡೆಯಲಾರ. ಅವನಿಗೆ ಸುಖವಿಲ್ಲ; ಪರಮಗತಿಯೂ ಇಲ್ಲ.\n\nನಾವು ಶಾಸ್ತ್ರದ ಕಟ್ಟಳೆಯನ್ನು ಬಿಟ್ಟು ನಮ್ಮಷ್ಟಕ್ಕೆ ನಾವು ಪ್ರಾಮಾಣಿಕವಾಗಿ ಬದುಕಲು ಸಾಧ್ಯವಿಲ್ಲ. ಏಕೆಂದರೆ\nನಮಗೆ ಯಾವುದು ಸರಿ, ಯಾವುದು ತಪ್ಪು ಎನ್ನುವ ಪರಿಜ್ಞಾನವಿರುವುದಿಲ್ಲ. ನಮಗೆ ಇಷ್ಟವಾದುದು ಸರಿ ಎಂದು\nನಾವು ತಿಳಿದುಕೊಳ್ಳುತ್ತೇವೆ. ನಮಗೆ ಯಾವುದು ತಿಳುವಳಿಕೆ ಕೊಡುತ್ತವೋ ಅವು ಶಾಸ್ತ್ರಗಳು. ಜಗತ್ತಿನ ಅನೇಕ\nಸಂಗತಿಗಳನ್ನು ನಮ್ಮ ಅನುಷ್ಠಾನದಲ್ಲಿ ಅಳವಡಿಸಿಕೊಳ್ಳಲು ಕೇವಲ ಆತ್ಮಶಕ್ತಿ ಮತ್ತು ಪ್ರಾಮಾಣಿಕತೆ ಸಾಲದು.\nಇದು ಸರಿ ಇದು ತಪ್ಪು ಎಂದು ತೀರ್ಮಾನ ಮಾಡಲು ಶಾಸ್ತ್ರಗಳು ಬೇಕೇ ಬೇಕು. ನಾವು ನಮ್ಮ ಅನುಭವದಿಂದ\n\nಇಡೀ ಪ್ರಪಂಚವನ್ನು ಗ್ರಹಿಸಲು ಸಾಧ್ಯವಿಲ್ಲ. ನಮ್ಮ ಬುದ್ಧಿ ಸೀಮಿತ, ನಮ್ಮ ತರ್ಕ ಸೀಮಿತ, ನಮ್ಮ ಆತ್ಮಸಾಕ್ಷಿ\nಸೀಮಿತ, ನಮ್ಮ ಪ್ರಾಮಾಣಿಕತೆ ಸೀಮಿತ. ಹಾಗಾಗಿ ನಾವು ಸೀಮಿತವಾದ ಅನುಭವದಿಂದ ಇಡೀ ವಿಶ್ವದ\nಸತ್ಯವನ್ನು ತಿಳಿಯಲು ಸಾಧ್ಯವಿಲ್ಲ. ಈ ಕಾರಣದಿಂದ ಭಗವಂತ; ಆತ ಜಗತ್ತಿಗೆ ಕೊಟ್ಟ ವೇದಾದಿ ಶಾಸ್ತ್ರಗಳು; ಆ\nಶಾಸ್ತ್ರವನ್ನು ಅರ್ಥಮಾಡಿಕೊಂಡು ನಮಗೆ ತಿಳಿ ಹೇಳಿದ ದೇವರನ್ನು ಬಲ್ಲ ಜ್ಞಾನಿಗಳು-ಇವರಿಂದ ನಾವು\nನಿಜವನ್ನು ಅರಿಯಬೇಕು. ಇಲ್ಲದಿದ್ದರೆ ಸಿದ್ಧಿ ಸಾಧ್ಯವಿಲ್ಲ.\n",
  "16.24": "ತಸ್ಮಾತ್‌ ಶಾಸ್ತ್ರಮ್‌ ಪ್ರಮಾಣಂ ತೇ ಕಾರ್ಯ ಅಕಾರ್ಯ ವ್ಯವಸ್ಥಿತೌ |\nಜ್ಞಾತ್ವಾ ಶಾಸ್ತ್ರ ವಿಧಾನ ಉಕ್ತಮ್‌ ಕರ್ಮ ಕರ್ತುಮ್‌ ಇಹ ಅರ್ಹಸಿ -ಅದರಿಂದ ಬೇಕು-ಬೇಡಗಳ ತೀರ್ಮಾನಕ್ಕೆ\nವಿನಗೆ ಶಾಸ್ತ್ರವೇ ಪ್ರಮಾಣ. ಶಾಸ್ತ್ರದ ಕಟ್ಟಳೆಯನ್ನರಿತು ಇಲ್ಲಿ ಕರ್ಮ ಮಾಡಲೆಳಸು.\n\nಎಲ್ಲಾ ಬೇಕು ಬೇಡಗಳಿಗೆ ಶಾಸ್ತ್ರವೇ ಪ್ರಮಾಣ. ಆದ್ದರಿಂದ ನಾವು ಶಾಸ್ತ್ರದಲ್ಲಿ ಹೇಳುವುದನ್ನು ಮೊದಲು\nನಂಬಬೇಕು. ಆಗ ಅದನ್ನು ತಿಳಿಯಲು ಸಾಧ್ಯವಾಗುತ್ತದೆ. ಶಾಸ್ತ್ರದಲ್ಲಿ ಹೀಗೆ ಮಾಡು, ಹೀಗೆ ಮಾಡಬೇಡ ಎಂದು\nಹೇಳಿರುವವರು- ಅದರಿಂದಾಗುವ ಪರಿಣಾಮವನ್ನು ಸಾಕ್ಷಾತ್ಮರಿಸಿಕೊಂಡ ಜ್ಞಾನಿಗಳು. ಆದ್ದರಿಂದ ಕರ್ಮದ\nಕಟ್ಟಳೆಯನ್ನರಿತು ಕರ್ಮ ಮಾಡು ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.\n\nಇಲ್ಲಿ ಶಾಸ್ತ್ರ ಎಂದರೆ ನಾಲ್ಕು ವೇದಗಳು ಮತ್ತು ಅದಕ್ಕೆ ಪೂರಕವಾದ ಪಂಚರಾತ್ರ, ಮಹಾಭಾರತ,\nಮೂಲರಾಮಾಯಣ, ಮತ್ತು ಹದಿನೆಂಟು ಪುರಾಣಗಳು. ಇದನ್ನು ಬಿಟ್ಟು ಇತರ ಯಾವುದನ್ನೂ ಪೂರ್ಣವಾಗಿ\n\nಪ್ರಮಾಣವಾಗಿರಿಸಲು ಸಾಧ್ಯವಿಲ್ಲ.\n\nಇತಿ ಷೋಡಶೋ*ಧ್ಯಾಯಃ\nಹದಿನಾರನೆಯ ಅಧ್ಯಾಯ ಮುಗಿಯಿತು\n\nಅಧ್ಯಾಯ ಹದಿನೇಳು\n\nಕೃಷ್ಣ ಗೀತೆಯ ಆರಂಭದಲ್ಲಿ ಕರ್ಮದ ಬಗ್ಗೆ ವಿವರಿಸುತ್ತಾ: “ಫಲದ ನಂಟು ತೊರೆದು, ಭಗವಂತನ ಪೂಜೆಯೆಂದು\nಕರ್ಮ ಮಾಡು” ಎನ್ನುವ ಸಂದೇಶವನ್ನು ಕೊಟ್ಟ. ಕರ್ಮ ಮಾಡುವಾಗ ನಾವು ತಿಳಿದುಕೊಳ್ಳಬೇಕಾದ ಒಂದು\nಬಹಳ ಮುಖ್ಯವಾದ ವಿಚಾರವೆಂದರೆ: ಯಾವುದು ಸತ್ಕರ್ಮ ಮತ್ತು ಯಾವುದು ಅಸತ್ಮರ್ಮ ಎನ್ನುವದು. ಕೆಟ್ಟ\nಕೆಲಸ ಮತ್ತು ಒಳ್ಳೆಯ ಕೆಲಸ ಎನ್ನುವುದು ನಾವು ತಿಳಿದಷ್ಟು ಸರಳವಾಗಿ ತಿಳಿಯುವ ವಿಚಾರವಲ್ಲ. ನಮಗೆ\nಮೇಲ್ನೋಟಕ್ಕೆ ಒಳ್ಳೆಯ ಕೆಲಸ ಎಂದು ಕಂಡು ಬಂದದ್ದು ಕೆಟ್ಟ ಕೆಲಸವಾಗಿರಬಹುದು ಅಥವಾ ಕೆಟ್ಟ ಕೆಲಸವೆಂದು\nಕಾಣಿಸಿದ್ದು ಒಳ್ಳೆಯ ಕೆಲಸವಾಗಿರಬಹುದು. ಇಲ್ಲಿ ಕೆಲಸದ ಹಿಂದಿರುವ ಭಾವ ಮುಖ್ಯವಾಗುತ್ತದೆ. ಒಂದೇ ಕ್ರಿಯೆ\nಅದರ ಹಿಂದಿನ ಭಾವಕ್ಕನುಗುಣವಾಗಿ ಸತ್ಕರ್ಮವಾಗಬಹುದು ಅಥವಾ ದುಷ್ಕರ್ಮವಾಗಬಹುದು.\nಉದಾಹರಣೆಗೆ: ಮಹಾಭಾರತ ಯುದ್ಧ. ಈ ಯುದ್ಧದಲ್ಲಿ ಪಾಂಡವರೂ ಪಾಲ್ಗೊಂಡಿದ್ದರು ಮತ್ತು ಕೌರವರೂ\nಪಾಲ್ಗೊಂಡಿದ್ದರು. ಪಾಂಡವರಲ್ಲಿ ಸಾತ್ವಿಕವಾದ ಮನೋವೃತ್ತಿ ಇತ್ತು. ಅವರು ಎಂದೂ ಸಾಮಾಜಿಕವಾಗಿ ತಾವು\nದೊಡ್ಡ ಸ್ಥಾನವನ್ನು ಗಳಿಸಬೇಕು(ರಾಜಸ ಭಾವನೆ), ಕೌರವರನ್ನು ಮಣ್ಣು ಮುಕ್ಕಿಸಬೇಕು(ತಾಮಸ ಭಾವನೆ)\nಎನ್ನುವ ಭಾವನೆಯಿಂದ ಯುದ್ಧ ಮಾಡಿಲ್ಲ. ಆದರೆ ದುರ್ಯೋಧನನಲ್ಲಿ ಇದ್ದದ್ದು ಕೇವಲ ರಾಜಸ ಮತ್ತು ತಾಮಸ\nಭಾವನೆ. ಈ ಕಾರಣದಿಂದ ಪಾಂಡವರು ಮಾಡಿದ ಯುದ್ಧ ಸಾತ್ವಿಕ ಯುದ್ಧವಾದರೆ, ಕೌರವರು ಮಾಡಿದ ಯುದ್ಧ\nತಾಮಸ ಯುದ್ಧವಾಯಿತು. ಆದ್ದರಿಂದ ನಾವು ಸತ್ಕರ್ಮ ಯಾವುದು ಅಸತ್ಮರ್ಮ ಯಾವುದು ಎನ್ನುವ\nಜ್ಞಾನವನ್ನು ಪಡೆದು ಕರ್ಮ ಮಾಡುವುದು ಬಹಳ ಮುಖ್ಯವಾಗುತ್ತದೆ. ಕರ್ಮ ಎನ್ನುವುದು ಸತ್ವ, ರಜಸ್ಸು,\nತಮಸ್ಸುಗಳೆಂಬ ಮೂರು ವಿಧವಾದ ತ್ರಿಗುಣಗಳ ಪರಿಧಿಯಲ್ಲೇ ನಡೆಯುತ್ತದೆ. ನಾವು ಮಾಡುವ ಯಜ್ಞ, ದಾನ,\nತಪಸ್ಸು; ನಾವು ಸೇವಿಸುವ ಆಹಾರ, ಎಲ್ಲದರಲ್ಲೂ ಈ ಗುಣತ್ರಯಗಳ ಪ್ರಭಾವ ಸೇರಿಕೊಂಡಿರುತ್ತದೆ. ಈ\nಗುಣತ್ರಯಗಳ ಪ್ರಭಾವ ನಮ್ಮ ಕರ್ಮದ ಮೇಲೆ ಹೇಗಾಗುತ್ತದೆ ಎನ್ನುವುದನ್ನು ನಾವು ಸಾಧ್ಯವಾದಷ್ಟು ಅರಿತು,\nಸತ್ವದ ಪರಿಧಿಯೊಳಗೆ ಕರ್ಮಾಚರಣೆ ಮಾಡಬೇಕು. ಈ ಅಧ್ಯಾಯ ಮುಖ್ಯವಾಗಿ ಯಾವ ಅನುಸಂಧಾನದಿಂದ\nಕರ್ಮ ಮಾಡಿದಾಗ ಆ ಕ್ರಿಯೆ ಸಾತ್ವಿಕ, ರಾಜಸ ಅಥವಾ ತಾಮಸ ಕ್ರಿಯೆಯಾಗುತ್ತದೆ ಎನ್ನುವುದನ್ನು\nವಿವರಿಸುತ್ತದೆ.\n\nಹಿಂದಿನ ಅಧ್ಯಾಯದ ಕೊನೆಯಲ್ಲಿ ಕೃಷ್ಣ “ಶಾಸ್ತ್ರದ ಕಟ್ಟಳೆಯನ್ನು ಮೀರಿ ಇಷ್ಟಬಂದಂತೆ ನಡೆವವನು ಸಿದ್ಧಿಯನ್ನು\nಪಡೆಯಲಾರ, ಅವನಿಗೆ ಸುಖವಿಲ್ಲ, ಪರಮಗತಿಯೂ ಇಲ್ಲ” ಎಂದು ಹೇಳಿದ್ದ. ಇಲ್ಲಿ ನಮಗೆ ಒಂದು ಪ್ರಶ್ನೆ\nಬರುತ್ತದೆ. ಶಾಸ್ತ್ರದ ಕಟ್ಟಳೆ ತಿಳಿಯದವರು-ನಂಬಿಕೆಯಿಂದ ಕರ್ಮ ಮಾಡುತ್ತಾರೆ-ಅಂತವರ ಗತಿ ಏನು? ಎಂದು.\nನಮ್ಮ ಪರವಾಗಿ ಅರ್ಜುನ ಕೃಷ್ಣನಲ್ಲಿ ಈ ಪ್ರಶ್ನೆಯನ್ನು ಕೇಳುವುದರೊಂದಿಗೆ ಈ ಅಧ್ಯಾಯ ಪ್ರಾರಂಭವಾಗುತ್ತದೆ.\nಬನ್ನಿ ಅರ್ಜುನನೊಂದಿಗೆ ನಾವೂ ಸೇರಿಕೊಂಡು ಭಗವಂತನ ಉಪದೇಶವನ್ನು ಆಲಿಸೋಣ.\n\nಅರ್ಜುನ ಉವಾಚ ।\nಯೇ ಶಾಸ್ತ್ರವಿಧಿಮುತ್ಸ ಜ್ಯ ಯಜಂತೇ ಶ್ರದ್ಧಯಾ$ನ್ವಿತಾಃ |\nತೇಷಾಂ ನಿಷ್ಠಾ ತು ಕಾ ಕೃಷ್ಣ ಸತ್ತಮಾಹೋ ರಜಸ್ತಮಃ ॥೧॥\n\nಅರ್ಜುನಃ ಉವಾಚ- ಅರ್ಜುನ ಕೇಳಿದನು:\n\nಯೇ ಶಾಸ್ತ್ರವಿಧಿಮ್‌ ಉತ್ಸ ಜ್ಯ ಯಜಂತೇ ಶ್ರದ್ಧಯಾ ಅನ್ವಿತಾಃ |\n\nತೇಷಾಂ ನಿಷ್ಠಾ ತು ಕಾ ಕೃಷ್ಣ ಸತ್ತ್ರಮ್‌ ಆಹೋ ರಜಃ ತಮಃ -- ಕೆಲವರು ಶಾಸ್ತ್ರದ ಕಟ್ಟಳೆ ಅರಿಯದೇ ಬಿಟ್ಟರೂ\nನಂಬಿಕೆಯಿಂದ ನಡೆದುಕೊಳ್ಳುತ್ತಾರೆ. ಅಂತವರ ನೆಲೆ ಎಂತಹದು ಕೃಷ್ಣಾ? ಸತ್ವವೇ, ರಜಸ್ಸೇ ಅಥವಾ\nತಮಸ್ಸೇ?\n\nನಾವು ವೇದಾಧ್ಯಯನ ಮಾಡಿಲ್ಲ , ನಮಗೆ ಶಾಸ್ತ್ರದ ವಿಧಿ ಗೊತ್ತಿಲ್ಲ, ಆದರೆ ಶಾಸ್ತ್ರ ತಿಳಿಯದೇ ಇದ್ದುದಕ್ಕಾಗಿ\nಪಶ್ಚಾತ್ತಾಪವಿದೆ; ಶಾಸ್ತ್ರದ ಬಗ್ಗೆ ಶ್ರದ್ಧೆ ಇದೆ, ಅದರ ಪ್ರಕಾರ ಬದುಕಬೇಕು ಎನ್ನುವ ಬಯಕೆ ಇದೆ. ತಿಳಿದವರು\nಹೇಳುತ್ತಾರೆ: \"ಯದೇವ ವಿದ್ಯಯಾ ಕರೋತಿ ಶ್ರದ್ಧೆಯ.. ಅಂದರೆ “ನೀನು ಏನನ್ನು ಮಾಡಿದರೂ ತಿಳಿದು ಮಾಡು.\nಜ್ಞಾನ ಪೂರ್ವಕವಾಗಿ ಮಾಡಿದ ಕರ್ಮ ಸಫಲ. ಇಲ್ಲದಿದ್ದರೆ ಅದು ವ್ಯರ್ಥ” ಎಂದು. ಹೀಗಿರುವಾಗ ಒಬ್ಬ\nಶ್ರದ್ಧೆಯಿಂದ ಮಾಡುವ ಕರ್ಮ ವ್ಯರ್ಥವೋ? ಇದು ಅರ್ಜುನನ ಪ್ರಶ್ನೆ.\n\nಇಲ್ಲಿ “ಶ್ರದ್ಧಾ' ಅಂದರೆ-ಅತೀಂದ್ರಿಯವಾಗಿರತಕ್ಕ, ನಮ್ಮನ್ನು ನಿಯಂತ್ರಿಸುವ ಅಗೋಚರ ಶಕ್ತಿಯ ಬಗ್ಗೆ\nನಮಗಿರುವ ನಂಬಿಕೆ. ಅರ್ಥಾತ್‌: ಭಗವಂತನ ಮೇಲೆ ನಂಬಿಕೆ, ಶಾಸ್ತ್ರದ ಮೇಲೆ ನಂಬಿಕೆ, ಪಾಪ-ಪುಣ್ಯದ\nನಂಬಿಕೆ, ಎಲ್ಲವನ್ನೂ ನಿಯಂತ್ರಿಸುವ ಪರಶಕ್ತಿ ಒಂದಿದೆ ಎನ್ನುವ ನಂಬಿಕೆ. ಮಹಾಭಾರತದಲ್ಲಿ ಹೇಳುವಂತೆ:\n'ಕರ್ಮಕ್ಕೆ ಫಲವಿದೆ. ಎನ್ನುವ ನಂಬಿಕೆಯೇ ಮನುಷ್ಯನ ಬದುಕಿನ ಆಧಾರ ಸ್ಥಂಭ... ಹೀಗಿರುವಾಗ\nನಂಬಿಕೆಯೊಂದಿಗ",
  "17.1": "ಅರ್ಜುನಃ ಉವಾಚ- ಅರ್ಜುನ ಕೇಳಿದನು:\n\nಯೇ ಶಾಸ್ತ್ರವಿಧಿಮ್‌ ಉತ್ಸ ಜ್ಯ ಯಜಂತೇ ಶ್ರದ್ಧಯಾ ಅನ್ವಿತಾಃ |\n\nತೇಷಾಂ ನಿಷ್ಠಾ ತು ಕಾ ಕೃಷ್ಣ ಸತ್ತ್ರಮ್‌ ಆಹೋ ರಜಃ ತಮಃ -- ಕೆಲವರು ಶಾಸ್ತ್ರದ ಕಟ್ಟಳೆ ಅರಿಯದೇ ಬಿಟ್ಟರೂ\nನಂಬಿಕೆಯಿಂದ ನಡೆದುಕೊಳ್ಳುತ್ತಾರೆ. ಅಂತವರ ನೆಲೆ ಎಂತಹದು ಕೃಷ್ಣಾ? ಸತ್ವವೇ, ರಜಸ್ಸೇ ಅಥವಾ\nತಮಸ್ಸೇ?\n\nನಾವು ವೇದಾಧ್ಯಯನ ಮಾಡಿಲ್ಲ , ನಮಗೆ ಶಾಸ್ತ್ರದ ವಿಧಿ ಗೊತ್ತಿಲ್ಲ, ಆದರೆ ಶಾಸ್ತ್ರ ತಿಳಿಯದೇ ಇದ್ದುದಕ್ಕಾಗಿ\nಪಶ್ಚಾತ್ತಾಪವಿದೆ; ಶಾಸ್ತ್ರದ ಬಗ್ಗೆ ಶ್ರದ್ಧೆ ಇದೆ, ಅದರ ಪ್ರಕಾರ ಬದುಕಬೇಕು ಎನ್ನುವ ಬಯಕೆ ಇದೆ. ತಿಳಿದವರು\nಹೇಳುತ್ತಾರೆ: \"ಯದೇವ ವಿದ್ಯಯಾ ಕರೋತಿ ಶ್ರದ್ಧೆಯ.. ಅಂದರೆ “ನೀನು ಏನನ್ನು ಮಾಡಿದರೂ ತಿಳಿದು ಮಾಡು.\nಜ್ಞಾನ ಪೂರ್ವಕವಾಗಿ ಮಾಡಿದ ಕರ್ಮ ಸಫಲ. ಇಲ್ಲದಿದ್ದರೆ ಅದು ವ್ಯರ್ಥ” ಎಂದು. ಹೀಗಿರುವಾಗ ಒಬ್ಬ\nಶ್ರದ್ಧೆಯಿಂದ ಮಾಡುವ ಕರ್ಮ ವ್ಯರ್ಥವೋ? ಇದು ಅರ್ಜುನನ ಪ್ರಶ್ನೆ.\n\nಇಲ್ಲಿ “ಶ್ರದ್ಧಾ' ಅಂದರೆ-ಅತೀಂದ್ರಿಯವಾಗಿರತಕ್ಕ, ನಮ್ಮನ್ನು ನಿಯಂತ್ರಿಸುವ ಅಗೋಚರ ಶಕ್ತಿಯ ಬಗ್ಗೆ\nನಮಗಿರುವ ನಂಬಿಕೆ. ಅರ್ಥಾತ್‌: ಭಗವಂತನ ಮೇಲೆ ನಂಬಿಕೆ, ಶಾಸ್ತ್ರದ ಮೇಲೆ ನಂಬಿಕೆ, ಪಾಪ-ಪುಣ್ಯದ\nನಂಬಿಕೆ, ಎಲ್ಲವನ್ನೂ ನಿಯಂತ್ರಿಸುವ ಪರಶಕ್ತಿ ಒಂದಿದೆ ಎನ್ನುವ ನಂಬಿಕೆ. ಮಹಾಭಾರತದಲ್ಲಿ ಹೇಳುವಂತೆ:\n'ಕರ್ಮಕ್ಕೆ ಫಲವಿದೆ. ಎನ್ನುವ ನಂಬಿಕೆಯೇ ಮನುಷ್ಯನ ಬದುಕಿನ ಆಧಾರ ಸ್ಥಂಭ... ಹೀಗಿರುವಾಗ\nನಂಬಿಕೆಯೊಂದಿಗೆ ಶ್ರದ್ಧೆ ಇದ್ದು, ಶಾಸ್ತ್ರದ ತಿಳುವಳಿಕೆ ಇಲ್ಲದೇ ಇದ್ದರೆ ಅಂತವರ ನೆಲೆ ಏನು? “ಎಲ್ಲರನ್ನು ಕರ್ಷಣೆ\nಮಾಡುವ(ಕೃಷ್ಣ) ನೀನು ಇಂತವರನ್ನು ಎಲ್ಲಿಗೆ ಕರ್ಷಣೆ ಮಾಡುತ್ತೀಯ? ಅಂಥವರ ನಿಷ್ಠೆ ಸಾತ್ವಿಕವೋ,\nರಾಜಸವೋ ಅಥವಾ ತಾಮಸವೋ?” ಎಂದು ನಮ್ಮ ನಿಮ್ಮೆಲ್ಲರಿಗಿರುವ ಈ ಗೊಂದಲದ ಪ್ರಶ್ನೆಯನ್ನು ಅರ್ಜುನ\nಕೃಷ್ಣನಲ್ಲಿ ಕೇಳುತ್ತಾನೆ.",
  "17.2": "ಭಗವಾನ್‌ ಉವಾಚ -ಭಗವಂತ ಹೇಳಿದನು:\nತ್ರಿವಿಧಾ ಭವತಿ ಶ್ರದ್ಧಾ ದೇಹಿನಾಂ ಸಾ ಸ್ವಭಾವಜಾ ।\nಸಾತ್ವಿಕೀ ರಾಜಸೀ ಚ ಏವ ತಾಮಸೀ ಚ ಇತಿ ತಾಂ ಶೃಣು -ಜೀವಿಗಳ ಹುಟ್ಟುಗುಣದಿಂದಲೇ ಹುಟ್ಟಿಬರುವ ಈ\n\nನಂಬಿಕೆ ಮೂರು ತೆರನಾಗಿದೆ: ಸಾತ್ವಿಕ, ರಾಜಸ, ಮತ್ತು ತಾಮಸ. ಅದರ ಬಗೆಯನ್ನಾಲಿಸು.\n\nಸಾಧನಾ ಶರೀರದಲ್ಲಿರುವ ಜೀವಗಳು ಮೂಲಭೂತವಾಗಿ ಮೂರು ತೆರನಾಗಿರುತ್ತವೆ. ಅದು ಸಾತ್ವಿಕ, ರಾಜಸ\nಮತ್ತು ತಾಮಸ. ಇದರ ಮೇಲೆ ಪರಿಸರದ ಮತ್ತು ಮನೆತನದ ಪ್ರಭಾವದಿಂದ ಮಾನಸಿಕವಾಗಿ ನಾವು ಮತ್ತೆ\nಮೂರು ತೆರನಾದ ಶ್ರದ್ಧೆಯನ್ನು ಬೆಳಸಿಕೊಳ್ಳುತ್ತೇವೆ. ಆದ್ದರಿಂದ ಸ್ವರೂಪತಃ ಸಾತ್ವಿಕನಾಗಿದ್ದರೂ ಕೂಡಾ ಆತ\nಮಾನಸಿಕವಾಗಿ ರಾಜಸನಾಗಿರಬಹುದು ಅಥವಾ ತಾಮಸನಾಗಿರಬಹುದು. ಉದಾಹರಣೆಗೆ ಸ್ವರೂಪತಃ\nಸಾತ್ವಿಕರಾಗಿದ್ದ ಗರ್ಗಾಚಾರ್ಯರು ತಾಮಸ ಪ್ರಭಾವಕ್ಕೊಳಗಾಗಿ ಕೃಷ್ಣನನ್ನು ಸೋಲಿಸುವ ಮಗ ಹುಟ್ಟಬೇಕು\nಎಂದು ತಪಸ್ಸನ್ನಾಚರಿಸಿರುವ ಕಥೆಯನ್ನು ಹಿಂದೆ ನೋಡಿದ್ದೇವೆ. ಮಾನಸಿಕವಾಗಿ ಬರುವ ಈ ಬಾಹ್ಯ ಶ್ರದ್ಧೆ ಜನ್ಮ\nಜನ್ಮಾಂತರದ್ದಲ್ಲ. ಆದರೆ ಸ್ವರೂಪ ಶ್ರದ್ಧೆ ಪ್ರತೀ ಜನ್ಮದಲ್ಲೂ ಸದಾ ಜೀವನೊಂದಿಗಿರುತ್ತದೆ. ಇದನ್ನು\nಸ್ಪಷ್ಟಪಡಿಸುವುದಕ್ಕೋಸ್ಕರ ಈ ಶ್ಲೋಕದಲ್ಲಿ 'ಏವ' ಮತ್ತು “ಚ' ಕಾರವನ್ನು ಒಟ್ಟಿಗೆ ಬಳಸಿದ್ದಾರೆ. ಜೀವಸ್ವರೂಪ-\nಸಾತ್ವಿಕೇವ, ರಾಜಸ್ಯೇವ ಅಥವಾ ತಾಮಸ್ಯೇವ-ಅದು ಬದಲಾಗುವುದಿಲ್ಲ. ಈ ಸ್ವರೂಪದ ಮೇಲಿರುವ ಬಾಹ್ಯ\nಶ್ರದ್ಧೆ- ಸಾತ್ವಿಕೇಚ, ರಾಜಸೇಚ, ತಾಮಸೇಚ-ಪ್ರಭಾವದಿಂದ ಬರುವಂತದ್ದು, ಗರಿಷ್ಠ ಒಂದು ಜನ್ಮಕ್ಕೆ\nಮೀಸಲಾಗಿರುವಂತಾದ್ದು. “ಈ ಮೂರು ವಿಧವಾದ ಶ್ರದ್ಧೆಯ ಬಗೆಯನ್ನಾಲಿಸು\" ಎಂದು ಕೃಷ್ಣ ಅರ್ಜುನನಲ್ಲಿ\nಹೇಳುತ್ತಾನೆ.\n",
  "17.3": "ಸತ್ವ ಅನುರೂಪಾ ಸರ್ವಸ್ಯ ಶ್ರದ್ಧಾ ಭವತಿ ಭಾರತ ।\n\nಶ್ರದ್ಧಾ ಮಯಃ ಅಯಮ್‌ ಪುರುಷಃ ಯಃ ಯತ್‌ ಶ್ರದ್ಧ ಸಃ ಏವ ಸಃ -ಭಾರತ, ಸ್ವಭಾವಕ್ಕೆ ತಕ್ಕಂತೆ ಎಲ್ಲರ\nನಂಬಿಕೆಯೂ ಇರುತ್ತದೆ. ಈ ಜೀವ ನಂಬಿಕೆಯ ಸ್ವರೂಪವೇ. ಅವನ ನಂಬಿಕೆ ಎಂತಹದ್ದೋ ಅವನು ಅಂತವನು.\n\nಜೀವದ ಸ್ವರೂಪಕ್ಕೆ ಅನುಗುಣವಾಗಿಯೇ ಮೂಲ ಶ್ರದ್ಧೆ ಇರುವುದು. ಆದರೆ ಕೆಲವೊಮ್ಮೆ ಅದು ವ್ಯಕ್ತವಾಗದೇ\nಇರಬಹುದು. ಇದು ವ್ಯಕ್ತವಾಗದೇ ಇದ್ದಾಗ, ಮನಸ್ಸಿ ನಲ್ಲಿ ಯಾವ ಬಾಹ್ಯ ಪ್ರಭಾವ ಶ್ರದ್ಧೆ ಇದೆಯೋ ಅದೇ ಅವನ\nನಂಬಿಕೆಯಾಗುತ್ತದೆ. ಮನುಷ್ಯ ಶ್ರದ್ಧೆಯ ಕೈಗೊಂಬೆ. ಯಾರ ಸ್ವರೂಪ ಶ್ರದ್ಧೆ ಸಾತ್ವಿಕವೋ ಅವನು ಸಾತ್ವಿಕ;\nಯಾರ ಸ್ವರೂಪ ಶ್ರದ್ಧೆ ರಾಜಸವೋ ಅವನು ರಾಜಸ; ಯಾರ ಸ್ವರೂಪ ಶ್ರದ್ಧೆ ತಾಮಸವೋ ಅವನು ತಾಮಸ.\nಹಾಗಾಗಿ ಜೀವರಲ್ಲಿ ಮೂರು ವಿಧ: ಸಾತ್ವಿಕ ಶ್ರದ್ಧೆ ಇರುವ ಜೀವ-ಸಾತ್ವಿಕ ಜೀವ; ರಾಜಸ ಶ್ರದ್ಧೆ ಇರುವ ಜೀವ-\nರಾಜಸ ಜೀವ; ತಾಮಸ ಶ್ರದ್ಧೆ ಇರುವ ಜೀವ-ತಾಮಸ ಜೀವ. ನಾವು ಧ್ಯಾನದಿಂದ ಮನಸ್ಸನ್ನು ಸ್ಥಗನಗೊಳಿಸಿ,\nತುರಿಯ ಸ್ಥಿತಿಯನ್ನು ತಲುಪಿದಾಗ ಬಾಹ್ಯ ಶ್ರದ್ಧೆ ಕಣ್ಮರೆಯಾಗಿ ಕೇವಲ ಸ್ವರೂಪ ಶ್ರದ್ಧೆ ವ್ಯಕ್ತವಾಗುತ್ತದೆ.\n",
  "17.4": "ಯಜಂತೇ ಸಾತ್ವಿಕಾಃ ದೇವಾನ್‌ ಯಕ್ಷರಕ್ಷಾಂಸಿ ರಾಜಸಾಃ |\nಪ್ರೇತಾನ್‌ ಭೂತಗಣಾನ್‌ ಚ ಅನ್ಯೇ ಯಜಂತೇ ತಾಮಸಾಃ ಜನಾಃ -ಸಾತ್ವಿಕರ ಪೂಜೆ ದೇವತೆಗಳಿಗೆ ಸಲ್ಲುತ್ತದೆ,\nರಾಜಸರದು ಯಕ್ಷ-ರಾಕ್ಷಸರಿಗೆ. ತಾಮಸರ ಪೂಜೆ ಪ್ರೇತಗಳಿಗೆ, ಭೂತಗಣಗಳಿಗೆ ಸಲ್ಲುತ್ತದೆ.\n\nಈ ಶ್ಲೋಕವನ್ನು ಮೇಲ್ನೊ ೀಟದಲ್ಲಿ ನೋಡಿದರೆ ಏನೂ ಅರ್ಥವಾಗುವುದಿಲ್ಲ. ಮೇಲ್ನೊ ಟಕ್ಕೆ “ಸಾತ್ವಿಕರು\nದೇವತೆಗಳನ್ನು ಪೂಜೆ ಮಾಡುತ್ತಾರೆ; ರಾಜಸರು ಯಕ್ಷ-ರಾಕ್ಷಸರನ್ನು ಮತ್ತು ತಾಮಸರು ಭೂತ-ಪ್ರೇತಗಳನ್ನು\nಪೂಜಿಸುತ್ತಾರೆ” ಎಂದು ಹೇಳಿದಂತೆ ಕಾಣಿಸುತ್ತದೆ. ಆದರೆ ಇಲ್ಲಿ ಅಡಗಿರುವ ಮೂಲ ಅರ್ಥವೇ ಬೇರೆ. ನಮಗೆ\nತಿಳಿದಂತೆ ಸಾತ್ವಿಕರಾಗಲೀ, ರಾಜಸರಾಗಲೀ, ತಾಮಸರಾಗಲೀ-ಅವರು ಪೂಜೆ ಮಾಡುವುದು ಭಗವಂತನನ್ನು\nಅಥವಾ ದೇವತೆಗಳನ್ನು. ವಾಮಾಚಾರ ಮಾಡುವವರನ್ನು ಬಿಟ್ಟರೆ ಇನ್ಯಾರೂ ಪ್ರೇತ-ಪಿಶಾಚಿ-\nರಾಕ್ಷಸರನ್ನು ಪೂಜಿಸುವುದಿಲ್ಲ. ಆದ್ದರಿಂದ ಇಲ್ಲಿ ಹೇಳಿರುವ ಮೂಲ ಸಂದೇಶ ಅರ್ಥವಾಗಬೇಕಾದರೆ ನಾವು ಈ\nಶ್ಲೋಕವನ್ನು ಆಳವಾಗಿ ವಿಶ್ಲೇಷಿಸಬೇಕು. ಇಲ್ಲಿ 'ದೇವಾನ್‌' ಎಂದರೆ: ಭಗವಂತನ ಅನೇಕ ರೂಪಗಳು ಮತ್ತು\nಭಗವಂತನ ಪರಿವಾರ ದೇವತೆಗಳು' ಎಂದರ್ಥ. \"ಯಜಂತೇ ಸಾತ್ವಿಕಾ ದೇವಾನ್‌' ಎಂದರೆ-ಸಾತ್ವಿಕರು\nಭಗವಂತನ ಅನುಸಂಧಾನದಿಂದ ಮಾಡುವ ಪೂಜೆ ದೇವತೆಗಳನ್ನು ಸೇರುತ್ತದೆ ಎಂದರ್ಥ. ಅದೇ ರೀತಿ\n\"ಯಕ್ಷರಕ್ಷಾಂಸಿ ರಾಜಸಾಃ\" ಎಂದರೆ- ರಾಜಸರು ಮಾಡುವ ಪೂಜೆ ಯಕ್ಷ-ರಾಕ್ಷಸರನ್ನು ಸೇರುತ್ತದೆ ಎಂದರ್ಥ.\nರಾಜಸರು ಸಾಮಾನ್ಯವಾಗಿ ಭಗವಂತನ ಪಾರಮ್ಯದ ಎಚ್ಚರವಿಲ್ಲದೆ, ಭಯದಿಂದ, ದೇವತೆಗಳು ನಮಗೆ\nತೊಂದರೆ ಕೊಡದಿರಲಿ ಎನ್ನುವ ಹರಕೆ ಸಂದಾಯ ಭಾವನೆಯಿಂದ ಪೂಜೆ ಮಾಡುತ್ತಾರೆ. ಈ ರೀತಿ ಪೂಜೆ\nಮಾಡಿದಾಗ, ನಾವು ಭಗವಂತನಿಗೆಂದು ಸಲ್ಲಿಸುವ ಪೂಜೆಯನ್ನು ದೇವತೆಗಳ ಹೆಸರಿನ ಯಕ್ಷ-ರಾಕ್ಷಸರು ಬಂದು\nಸ್ವೀಕರಿಸುತ್ತಾರೆ. ಇನ್ನು ಮೂರನೆಯ ವರ್ಗ ತಾಮಸ. ಇವರು ಪೂಜೆ ಮಾಡುವುದು ತಮ್ಮ ಅಂತಸ್ತನ್ನು\nತೋರಿಸಿಕೊಳ್ಳುವುದಕ್ಕಾಗಿ. ಉದಾಹರಣೆಗೆ ದುರ್ಯೋಧನ ಪಾಂಡವರು ಮಾಡಿದ ಅಶ್ವಮೇಧ ಯಾಗವನ್ನು\nಮೀರಿಸುವ ಸಲುವಾಗಿ ಪೌಂಡ್ರಿಕ ಯಾಗ ಮಾಡಿಸಿದಂತೆ. ಹೀಗೆ ದುರುದ್ದೇಶದಿಂದ ತಾಮಸರು ಮಾಡುವ\nಪೂಜೆಯನ್ನು ಬಂದು ಸ್ವೀಕರಿಸುವವರು ದೇವತೆಗಳ ಹೆಸರಿನ ಭೂತ-ಪ್ರೇತಗಳು.\n\nಪೂಜೆಯಲ್ಲಿ ಕೇವಲ ಶ್ರದ್ಧೆ ಮುಖ್ಯವಲ್ಲ ಬದಲಿಗೆ ಅದು ಎಂತಹ ಶ್ರದ್ಧೆ ಎನ್ನುವುದು ಮುಖ್ಯ. ಶಾಸ್ತ್ರ ಗೊತ್ತಿಲ್ಲದಿದ್ದರೂ\nಕೂಡಾ, ಸಾತ್ವಿಕ ಶ್ರದ್ಧೆಯಿಂದ: “ಭಗವಂತಾ, ನನಗೆ ಏನೂ ಗೊತ್ತಿಲ್ಲ, ನಾನು ಭಕ್ತಿಯಿಂದ ನಿನ್ನನ್ನು ಆರಾಧನೆ\nಮಾಡುತ್ತೇನೆ, ನನ್ನ ತಪ್ಪನ್ನು ಕ್ಷಮಿಸು” ಎಂದು ಶರಣಾಗತಿಯಿಂದ ಬೇಡಿದರೆ ಆ ಪೂಜೆಯನ್ನು ಸ್ವತಃ\nಭಗವಂತನೇ ಬಂದು ಸ್ವೀಕಾರ ಮಾಡುತ್ತಾನೆ. ಆದರೆ ಸ್ವಾರ್ಥ, ಅಹಂಕಾರ, ಡಂಭದಿಂದ ಮಾಡುವ ರಾಜಸ\nಅಥವಾ ತಾಮಸ ಪೂಜೆಯನ್ನು ಭಗವಂತನಾಗಲೀ, ಅವನ ಪರಿವಾರ ದೇವತೆಗಳಾಗಲೀ ಸ್ವೀಕರಿಸುವುದಿಲ್ಲ.\n\nನಮ್ಮ ಕರ್ಮ ಕಾಮರಹಿತ(ನಿಷ್ಕಾಮ)ವಾಗಿರಬೇಕು. ಇಲ್ಲಿ ಕಾಮ ಅಂದರೆ ಕೆಟ್ಟಬಯಕೆ. ಬಯಕೆಯಲ್ಲಿ ಎಂದೂ\nಸ್ವಾರ್ಥವಿರಕೂಡಾದು. ನಾವು ನನಗೆ ಮಾತ್ರ ಒಳ್ಳೆಯದಾಗಲಿ ಎನ್ನುವ ಸಂಕುಚಿತ ಭಾವವನ್ನು ಬಿಟ್ಟುಬಿಡಬೇಕು.\n\nಪೂಜೆ ಪುನಸ್ಕಾರ ಮಾಡುವಾಗ ಯಾವುದೋ ಸಂಕುಚಿತ ಉದ್ದೇಶವಿಟ್ಟು ನಾವು ಪೂಜೆ ಮಾಡಬಾರದು.\nಉದಾಹರಣೆಗೆ: “ನನ್ನ ವ್ಯವಹಾರದಲ್ಲಿ ಏಳಿಗೆ ಆಗಲಿ ಎಂದು ಯಜ್ಞ ಮಾಡುವುದು; ಮಗಳಿಗೆ ಉತ್ತಮ ವರ ಸಿಗಲಿ\nಎನ್ನುವ ಫಲಾಪೇಕ್ಷೆಯಿಂದ ಪೂಜೆ ಮಾಡುವುದು ಇತ್ಯಾದಿ. ನಾವು ದೇವರಲ್ಲಿ ಈ ರೀತಿ ನಮ್ಮ ಕಾಮನೆಗಳ ಪಟ್ಟಿ\nಕೊಡಬಾರದು. ಯಾವುದು ಆಗಬೇಕು ಎನ್ನುವುದು ದೇವರಿಗೆ ಗೊತ್ತಿದೆ. ಯಾವುದು ಒಳ್ಳೆಯದು, ಯಾವುದು\nಕೆಟ್ಟದ್ದು ಎನ್ನುವುದು ಅವನಿಗೆ ಮಾತ್ರ ಗೊತ್ತಿರುವುದು. ಅದನ್ನು ಅವನು ಕೊಟ್ಟೇ ಕೊಡುತ್ತಾನೆ. ಹೀಗಿರುವಾಗ\nನಾವು ನಮ್ಮ ಇಂತಹ ಸಂಕುಚಿತ ಕಾಮದ ಪಟ್ಟಿಯನ್ನು ಹಿಡಿದುಕೊಂಡು ಕರ್ಮ ಮಾಡಿದಾಗ ಆಗುವ ದುರಂತ\nಘೋರ. ನಾವು ದೇವರಲ್ಲಿ ಯಾವುದೋ ಬಯಕೆಯನ್ನಿಟ್ಟು ಪೂಜೆ ಮಾಡಿಸುತ್ತೇವೆ. ಆ ಪೂಜೆಗಾಗಿ ಹಣ ವೆಚ್ಚ\nಮಾಡಿರುತ್ತೇವೆ. ಆದರೆ ಆ ಬಯಕೆ ಈಡೇರುವುದಿಲ್ಲ. ಆಗ ನಮಗೆ ದೇವರ ಮೇಲೆ ದ್ವೇಷ, ಹಣ ವ್ಯರ್ಥವಾಯಿತು\nಎನ್ನು ವ ಅಸಮಾಧಾನ. ಹೀಗಾದಾಗ ನಮ್ಮ ಪೂಜೆ ವ್ಯಾಪಾರವಾಗುತ್ತದೆ ಮತ್ತು ಅದು ಭೂತ-ಪ್ರೇತಗಳನ್ನು\nಸೇರುತ್ತದೆ. ದೇವರ ಪೂಜೆ ವ್ಯಾಪಾರವಲ್ಲ.",
  "17.5": "ಕರ್ಶಯಂತಃ ಶರೀರಸ್ಥಂ ಭೂತಗ್ರಾಮಮಚೇತಸಃ |\nಮಾಂ ಚೈವಾ",
  "17.6": "ಅಶಾಸ್ತ್ರ ವಿಹಿತಂ ಘೋರಂ ತಪ್ಯಂತೇ ಯೇ ತಪಃ ಜನಾಃ |\n\nಡಂಭ ಅಹಂಕಾರ ಸಂಯುಕ್ತಾಃ ಕಾಮ ರಾಗ ಬಲ ಅನ್ವಿತಾಃ\n\nಕರ್ಶಯಂತಃ ಶರೀರಸ್ಥಂ ಭೂತಗ್ರಾಮಮ್‌ ಅಚೇತಸಃ ।\n\nಮಾಂ ಚ ಏವ ಅಂತಃ ಶರೀರಸ್ಥಂ ತಾನ್‌ ವಿದ್ಧಿ ಆಸುರನಿಶ್ಚಯಾನ್‌ -- ಕೆಲವು ಜನರು ಶಾಸ್ತ್ರದ ಕಟ್ಟಳೆ ಮೀರಿ\nಕೆಟ್ಟ ತಪವನ್ನಾಚರಿಸುತ್ತಾರೆ; ಬೂಟಾಟಿಕೆಯಿಂದ ಮತ್ತು ಹಮ್ಮಿನಿಂದ. ಆಸೆ-ಆಸಕ್ತಿಗಳೇ ಅವರ ಸಾಧನೆಗೆ\nಬೆಂಬಲ. ಇಂತಹ ತಿಳಿಗೇಡಿಗಳು ತಮ್ಮ ದೇಹದಲ್ಲಿರುವ ಭೂತ ಸಮೂಹವನ್ನು [ದೇಹವನ್ನು ನಿಯಮಿಸುವ\nದೇವತಾಗಣವನ್ನು] ಕಡೆಗಣಿಸುತ್ತಾರೆ. ದೇಹದೊಳಗಿರುವ ನನ್ನ ಹಿರಿಮೆಯನ್ನು ಅಲ್ಲಗಳೆಯುತ್ತಾರೆ. ಅಂತವರು\nತಾಮಸ ಸ್ವಭಾವದವರು ಎಂದು ತಿಳಿ.\n\nಶ್ರದ್ಧೆಯಲ್ಲೇ ಅತ್ಯಂತ ನೀಚವಾದ ತಾಮಸ ಶ್ರದ್ಧೆ ಹೇಗಿರುತ್ತದೆ ಎನ್ನುವುದನ್ನು ಕೃಷ್ಣ ಇಲ್ಲಿ ವಿವರಿಸುತ್ತಾನೆ.\nಕೆಲವರು ಶಾಸ್ತ್ರದ ಕಟ್ಟಳೆ ಮೀರಿ ತಪಸ್ಸನ್ನಾಚರಿಸುತ್ತಾರೆ. ಆ ತಪಸ್ಸಿನ ಹಿಂದಿರುವ ಉದ್ದೇಶ ಘೋರ. ಇಲ್ಲಿ\nತಪಸ್ಸು ಅಂದರೆ ಕೇವಲ ಖುಷಿ-ಮುನಿಗಳು ಮಾಡುವ ತಪಸ್ಸು ಮಾತ್ರವಲ್ಲ. ಶ್ರದ್ಧೆಯಿಂದ ಮಾಡುವ ಯಾವ\nಕ್ರಿಯೆಯೂ ತಪಸ್ಸಾಗಬಹುದು[ಈ ಕುರಿತು ಹೆಚ್ಚಿನ ವಿವರಣೆಯನ್ನು ಈ ಅಧ್ಯಾಯದ ಮುಂದಿನ ಭಾಗ(ಶ್ಲೋಕ\n೧೪-೧೯)ದಲ್ಲಿ ಕಾಣಬಹುದು]. ತಪಸ್ಸು ಮಾಡುವಾಗ ನಾವು ನನಗೆ ಒಳ್ಳೆಯದಾಗಲಿ ಎಂದು ತಪಸ್ಸು\nಮಾಡಬಹುದು ಅಥವಾ ಲೋಕಕ್ಕೆ ಒಳ್ಳೆಯದಾಗಲಿ ಎಂದು ತಪಸ್ಸು ಮಾಡಬಹುದು. ಉದಾಹರಣೆಗೆ ಗಾಯತ್ರಿ:\n\nಇಲ್ಲಿ “ಧಿಯೋ ಯೋನಃ ಪ್ರಚೋದಯಾತ್‌” ಎನ್ನುವಲ್ಲಿ “ನಮಗೆಲ್ಲರಿಗೂ ಒಳ್ಳೆಯ ಬುದ್ಧಿ ಕೊಡು ದೇವರೇ”\nಎನ್ನುವ ಸಾತ್ವಿಕ ಶ್ರದ್ಧೆ ಇದೆ. ಲೋಕದಲ್ಲಿ ಎಲ್ಲರಿಗೂ ಒಳ್ಳೆಯದಾಗಲಿ ಎಂದು ಮಾಡುವ ತಪಸ್ಸು ಸಾತ್ವಿಕ\nತಪಸ್ಸು. ಇದನ್ನು ಬಿಟ್ಟು. “ನನಗೆ ಮಾತ್ರ ಒಳ್ಳೆಯದನ್ನು ಕೊಡು” ಎಂದು ಮಾಡುವ ಪೂಜೆ ರಾಜಸ.\n“ಇನ್ನೊಬ್ಬರು ಹಾಳಾಗಬೇಕು-ನಾನು ಒಳ್ಳೆಯದಾಗಬೇಕು” ಎಂದು ಮಾಡುವ ಪೂಜೆ. ತಾಮಸ. ಇವು\nಲೋಕಕಂಟಕವಾದ ಘೋರ ಶ್ರದ್ಧೆ.\n\nಶಾಸ್ತ್ರವಿಹಿತವಾದ ತಪಸ್ಸು ಎಂದರೆ: ಭಗವಂತನ ಪಾರಮ್ಯವನ್ನು ಅರಿತು, ಇನ್ನೊಬ್ಬರ ಬಗ್ಗೆ ಕೆಟ್ಟ ಯೋಚನೆ\nಮಾಡದೆ, ಲೋಕದಲ್ಲಿ ಎಲ್ಲರಿಗೂ ಒಳ್ಳೆಯದಾಗಲಿ ಎಂದು ಮಾಡುವ ತಪಸ್ಸು. 'ಸರ್ವೋತ್ಕರ್ಷೆ ದೇವ ದೇವಸ್ಯ\nವಿಷ್ಣೋ ಮಹಾ ತಾತ್ಪರ್ಯಂ'- ಸಮಸ್ತ ಶಾಸ್ತ್ರಗಳ ತಾತ್ಮರ್ಯ- “ಭಗವಂತ ಸರ್ವೋತ್ತಮ' ಎನ್ನುವುದು. ಇದನ್ನು\nಒಪ್ಪಿಕೊಳ್ಳದೇ ಇರುವುದು ಶಾಸ್ತ್ರ ವಿರುದ್ಧ. ಇದನ್ನು ಒಪ್ಪಿಕೊಂಡು ಲೋಕಕ್ಕೆ ಕೆಟ್ಟದಾಗಲಿ ಎನ್ನುವ ಭಾವನೆ\nಮನದಲ್ಲಿ ಮೂಡಿದರೆ ಅದೂ ಕೂಡಾ ಅಶಾಸ್ತ್ರವಿಹಿತವಾಗುತ್ತದೆ. ಯಾವುದು ಶಾಸ್ತ್ರವಿಹಿತ ಅಲ್ಲವೋ ಅದು\nಭಗವಂತನಿಗೆ ಪ್ರಿಯವಲ್ಲ. ಇನ್ನೊಬ್ಬರ ಬಗ್ಗೆ ಕೆಟ್ಟದ್ದನ್ನು ಬಯಸಿ, ಸ್ವಾರ್ಥದಿಂದ ಮಾಡುವ ಕರ್ಮ 'ಘೋರ ಕ್ರಿಯೆ'\nಎನಿಸುತ್ತದೆ ಎನ್ನುವ ಎಚ್ಚರವನ್ನು ಕೃಷ್ಣ ಇಲ್ಲಿ ಕೊಟ್ಟಿದ್ದಾನೆ. ಇಂತಹ ಕ್ರಿಯೆಯ ಹಿಂದೆ ಡಂಭಾಚಾರ ಮತ್ತು\nಅಹಂಕಾರವಿರುತ್ತದೆ. ಇದನ್ನು ದೇವತೆಗಳು ಎಂದೂ ಸ್ವೀಕರಿಸುವುದಿಲ್ಲ.\n\nಕೆಲವರು ತಮ್ಮ ದೈಹಿಕ ಬಲದಿಂದ ಇನ್ನೊಬ್ಬರನ್ನು ಬಗ್ಗುಬಡಿಯಬೇಕು ಎನ್ನುವ ದುಷ್ಟ ಉದ್ದೇಶವಿಟ್ಟು\nತಪವನ್ನಾಚರಿಸುತ್ತಾರೆ. ಯಾರು ತಮ್ಮ ಕಾಮನೆಗಳಿಗೆ ಅಡ್ಡಿಪಡಿಸುತ್ತಾರೋ, ತಮ್ಮ ಇಷ್ಟಾನಿಷ್ಠಗಳಿಗೆ\nಸ್ಪಂದಿಸುವುದಿಲ್ಲವೋ, ಅಂಥವರನ್ನು ಮುಗಿಸಬೇಕು ಎನ್ನುವ ಕೆಟ್ಟ ಚಿಂತನೆ ಇವರ ಮನಸ್ಸಿನಲ್ಲಿರುತ್ತದೆ. ಹೀಗೆ\nಡಂಭದಿಂದ, ಅಹಂಕಾರದಿಂದ, ಸಂಕುಚಿತ ಕಾಮದಿಂದ, ಸ್ವಾರ್ಥದಿಂದ, ತೋಳ್ಪಲದಿಂದ ಕ್ರಿಯೆ ಮಾಡುವವರು\nತಿಳಿಗೇಡಿಗಳು. ಇವರು ತಮ್ಮ ದೇಹವನ್ನು ದಂಡನೆ ಮಾಡಿ ತಪಸ್ಸನ್ನಾಚರಿಸುತ್ತಾರೆ.ಆದರೆ ಅವರಿಗೆ ತಮ್ಮ\nದೇಹದಲ್ಲಿರುವ ಭೂತಗ್ರಾಮದ(ದೇವತೆಗಳ ಸಮೂಹದ) ಎಚ್ಚರವಿರುವುದಿಲ್ಲ. ಸಮಸ್ತ ದೇವತಾಗಣವನ್ನು\nನಿರ್ಲಕ್ಷ್ಯ ಮಾಡಿ, ದೇವತೆಗಳ ಒಳಗಿರುವ ಭಗವಂತನನ್ನೂ ನಿರ್ಲಕ್ಷ್ಯ ಮಾಡಿ, ದೇಹದಂಡನೆ ಮಾಡಿಕೊಂಡು\nಅನುಷ್ಠಾನ ಮಾಡುವ ಇವರು ಅಸುರರೆನಿಸುತ್ತಾರೆ. ಇವರು 'ಇಂದ್ರಿಯ ಕರ್ಮವೇ ಸರ್ವಸ್ವ-ಅದರಿಂದಾಚೆಗೆ\nಏನೂ ಇಲ್ಲ' ಎಂದು ತಿಳಿದಿರುತ್ತಾರೆ.\n\nಕೃಷ್ಣನ ಈ ವಿವರಣೆಯನ್ನು ನೋಡಿದಾಗ ನಮ್ಮ-ನಿಮ್ಮೊಳಗಿರುವ ಈ ಅಸುರ(ಪ್ರಭಾವದಿಂದ ಬೆಳೆದ\nಅಂಧಃಶ್ರದ್ಧೆ ಎಷ್ಟು ಭಯಾನಕ ಎನ್ನುವ ಅಂಶ ನಮಗೆ ತಿಳಿಯುತ್ತದೆ. ಇದನ್ನು ನಾವು ನಮ್ಮ ಪ್ರತಿಯೊಂದು\nಕ್ರಿಯೆಯಲ್ಲೂ ಗುರುತಿಸಿಕೊಂಡು ತಿದ್ದಿಕೊಳ್ಳಬೇಕು. ಇದಕ್ಕಾಗಿ ಕೃಷ್ಣ ಮುಂದಿನ ಶ್ಲೋಕಗಳಲ್ಲಿ ಆಹಾರ, ತಪಸ್ಸು,\nದಾನ ಇತ್ಯಾದಿಯಲ್ಲಿ ಸಾತ್ವಿಕ, ರಾಜಸ ಮತ್ತು ತಾಮಸ ಪ್ರಭೇದ ಹೇಗಿರುತ್ತದೆ ಎನ್ನುವುದನ್ನು ವಿವರಿಸುತ್ತಾನೆ.\n",
  "17.7": "ಆಹಾರಃ ತು ಅಪಿ ಸರ್ವಸ್ಯ ತ್ರಿವಿಧಃ ಭವತಿ ಪ್ರಿಯಃ ।\nಯಜ್ಞಃ ತಪಃ ತಥಾ ದಾನಂ ತೇಷಾಂ ಭೇದಮ್‌ ಇಮಮ್‌ ಶೃಣು -ಎಲ್ಲರು ಉಣ್ಣುವ ಆಹಾರವೂ ಮೂರು\nತೆರನಾಗಿ ಮೆಚ್ಚಿಗೆಯಾಗುತ್ತದೆ. ಯಜ್ಞ, ತಪಸ್ಸು, ದಾನ ಕೂಡಾ. ಅವುಗಳ ಈ ಬಗೆಯನ್ನಾಲಿಸು.\n\nನಾವು ತಿನ್ನುವ ಆಹಾರ ಕೂಡಾ ಮೂರು ತೆರನಾಗಿರುತ್ತದೆ. ಸಾತ್ವಿಕ, ರಾಜಸ ಮತ್ತು ತಾಮಸ ಆಹಾರ. “ಅನ್ನಂ\nಅಷಿತಂ ತ್ರೇಧಾ ವಿಧ್ಯತೆ” (ಛಾಂದೋಗ್ಯೋಪನಿಷತ್‌-೫-೧) ಎನ್ನು ವಂತೆ ನಾವು ಸೇವಿಸುವ ಆಹಾರವನ್ನು\nನಮ್ಮೊಳಗಿರುವ ಪ್ರಾಣ ಮತ್ತು ವೈಶ್ವಾನರರು ಮೂರು ಬಗೆಯನ್ನಾಗಿ(ಸೂಕ್ಷ್ಮ, ಮಧ್ಯ ಮತ್ತು ಸ್ಥೂಲ) ವಿಂಗಡಿಸಿ\nಅದನ್ನು ದೇಹದ ವಿವಿಧ ಭಾಗಗಳಿಗೆ ಸರಬರಾಜು ಮಾಡುತ್ತಾರೆ. ನಮ್ಮ ಆಹಾರಕ್ಕೂ ಮನಸ್ಸಿಗೂ ನೇರ\nಸಂಬಂಧವಿದೆ. ಇದನ್ನು ನಮ್ಮ ಪ್ರಾಚೀನರು ಅರಿತಿದ್ದರು. ಅದಕ್ಕಾಗಿ ಮನಸ್ಸಿನ ಮೇಲೆ ಪ್ರಭಾವ ಬೀರುವ\nಆಹಾರವನ್ನು ಅವರು ನಿಷೇಧಿಸಿದರು. ಉದಾಹರಣೆಗೆ ಬೆಳ್ಳುಳ್ಳಿ. ಇದು ಔಷಧೀಯ ವಸ್ತು. ಆದರೆ ಇದನ್ನು ನಿತ್ಯ\nಆಹಾರದಲ್ಲಿ ಬಳಸುವುದನ್ನು ನಿಷೇಧಿಸಿದ್ದಾರೆ. ಏಕೆಂದರೆ ಇದು ನಮ್ಮ ಬುದ್ಧಿ ಬೆಳವಣಿಗೆಗೆ ಪೂರಕವಲ್ಲ. ಇದೇ\nರೀತಿ. ನುಗ್ಗೆಕಾಯಿ, ತೊಂಡೆಕಾಯಿ ಇತ್ಯಾದಿ. ಅಧ್ಯಯನ ಮಾಡುವವರಿಗೆ ಇದು ನಿಷಿದ್ಧ (ಔಷಧವಾಗಿ\nಬಳಸಬಹುದು). ಹೀಗೆ ಮನುಷ್ಯನ ಬುದ್ಧಿಗೆ ಯಾವ ವಿಧದ ಆಹಾರ ಸೂಕ್ತ ಎನ್ನುವುದನ್ನು ಮೊತ್ತ ಮೊದಲ ಬಾರಿಗೆ\nಕೃಷ್ಣ ಜಗತ್ತಿಗೆ ಕೊಟ್ಟ.\n\nಆಹಾರದ ಜೊತೆಗೆ ನಾವು ಮಾಡುವ ದೇವರ ಪೂಜೆ, ತಪಃ, ನಮ್ಮ ಚಿಂತನಾ ಕ್ರಮ, ದಾನ, ಜೀವನದ ನಡೆ,\nಮಾತು ಎಲ್ಲವುದರಲ್ಲೂ ಈ ಮೂರು ವಿಧವನ್ನು ಗುರುತಿಸಬಹುದು. ಕೃಷ್ಣ ಮುಂದಿನ ಶ್ಲೋಕಗಳಲ್ಲಿ ಆಹಾರ,\nಯಜ್ಞ, ತಪಸ್ಸು ಮತ್ತು ದಾನದಲ್ಲಿ ಈ ಮೂರು ಬಗೆಯನ್ನು ಗುರುತಿಸುವುದು ಹೇಗೆ ಎನ್ನುವುದನ್ನು ವಿವರಿಸುತ್ತಾನೆ.\n",
  "17.8": "ಆಯುಃ ಸತ್ವ ಬಲ ಆರೋಗ್ಯ ಸುಖ ಪ್ರೀತಿ ವಿವರ್ಧನಾಃ ।\n\nರಸ್ಯಾಃ ಸ್ನಿಗ್ಧಾಃ ಸ್ಥಿರಾ ಹೃದ್ಯಾಃ ಆಹಾರಾಃ ಸಾತ್ವಿಕ ಪ್ರಿಯಾಃ -ಇವು ಸಾತ್ವಿಕರಿಗೆ ಮೆಚ್ಚುಗೆಯಾದ ತಿನಿಸುಗಳು:\nಆಯುಸ್ಸು, ಒಳ್ಳೆಯತನ, ತ್ರಾಣ, ಆರೋಗ್ಯವನ್ನು ಹೆಚ್ಚಿಸುವಂತವು; ಬಹಳ ಕಾಲ ಮೆಚ್ಚಿಗೆಯಾಗುವಂತವು;\nತಿಂದಾಗ ಖುಷಿಯಾಗುವಂತವು; ರುಚಿಯಾದಂತವು; ಕಸುವಿರುವಂತವು; ಧೀರ್ಥಕಾಲ ಪರಿಣಾಮ\n\nಬೀರುವಂತವ; ಮತ್ತೆಮತ್ತೆ ಮನ ಸೆಳೆಯುವಂತವು.\n\nಈ ಶ್ಲೋಕದಲ್ಲಿ ಕೃಷ್ಣ ಸಾತ್ವಿಕ ಆಹಾರದ ಬಗ್ಗೆ ವಿವರಿಸಿದ್ದಾನೆ. ಯಾವ ಆಹಾರ ನಮ್ಮ ಆಯಸ್ಸಿನ ವೃದ್ಧಿಗೆ\nಪೂರಕವೋ; ಯಾವ ಆಹಾರ ನಮಗೆ ಸೌಮ್ಯ ಸ್ವಭಾವವನ್ನು ಕೊಡುತ್ತದೋ; ಯಾವ ಆಹಾರ ದೇಹಕ್ಕೆ\n\nಪೌಷ್ಟಿಕಾಂಶವನ್ನು ಕೊಡುತ್ತದೋ; ಯಾವ ಆಹಾರ ಆರೋಗ್ಯವನ್ನು ಕೊಡುತ್ತದೋ ಅಂತಹ ಆಹಾರ ಸಾತ್ವಿಕ\nಆಹಾರ. ಈ ಆಹಾರವನ್ನು ನೋಡಿದಾಗ ನಮಗೆ ಕೆಟ್ಟ ಭಾವನೆ ಬರುವುದಿಲ್ಲ. ಅದು ರಸವತ್ತಾಗಿರುತ್ತದೆ,\nರುಚಿಯಾಗಿರುತ್ತದೆ. ಇದನ್ನು ತಿಂದಾಗ ನಮ್ಮ ಹೊಟ್ಟೆ ತುಂಬುತ್ತದೆ ಮತ್ತು ತಕ್ಷಣ ಹಸಿವೆಯಾಗುವುದಿಲ್ಲ.\nನೋಡಲು ಹೃದಯಂಗಮವಾಗಿರುತ್ತದೆ, ತಿಂದ ನೆನಪು ಉಳಿಯುವಂತಿರುತ್ತದೆ.\n\nನಿಜವಾದ ಸಾತ್ವಿಕರು ಏನು ತಿನ್ನು ತ್ತಾರೋ ಅದು ಸಾತ್ವಿಕ ಆಹಾರವಾಗಿರುತ್ತದೆ. ಪ್ರಕೃತಿ ಸಹಜವಾದ,\nರಸವತ್ತಾದ, ರುಚಿಯಾದ, ಹಣ್ಣು-ಹಂಪಲು, ಗಡ್ಡೆ-ಗೆಣಸು, ಬೇಳೆ-ಕಾಳು, ಕಂದ-ಮೂಲಗಳು ಸಾಮಾನ್ಯವಾಗಿ\nಸಾತ್ವಿಕ ಆಹಾರವಾಗಿರುತ್ತದೆ. ಆಯುಸ್ಸನ್ನು ಹೆಚ್ಚಿಸುವ ಶುದ್ಧ ತುಪ್ಪ(ಮಿತವಾಗಿ ಬಳಸಿದಾಗ) ಸಾತ್ವಿಕ ಆಹಾರ.\n\nಕಟ್ಟಮ್ಸಲವಣಾತ್ಯುಷ್ಟತೀಕ್ಷರೂಕ್ಷವಿದಾಹಿನಃ ।\n\nಆಹಾರಾ ರಾಜಸಸ್ಯೇಷ್ಟಾ ದುಃಖಶೋಕಾಮಯಪ್ರದಾಃ",
  "17.9": "ರಸ್ಯಾಃ ಸ್ನಿಗ್ಧಾಃ ಸ್ಥಿರಾ ಹೃದ್ಯಾಃ ಆಹಾರಾಃ ಸಾತ್ವಿಕ ಪ್ರಿಯಾಃ -ಇವು ಸಾತ್ವಿಕರಿಗೆ ಮೆಚ್ಚುಗೆಯಾದ ತಿನಿಸುಗಳು:\nಆಯುಸ್ಸು, ಒಳ್ಳೆಯತನ, ತ್ರಾಣ, ಆರೋಗ್ಯವನ್ನು ಹೆಚ್ಚಿಸುವಂತವು; ಬಹಳ ಕಾಲ ಮೆಚ್ಚಿಗೆಯಾಗುವಂತವು;\nತಿಂದಾಗ ಖುಷಿಯಾಗುವಂತವು; ರುಚಿಯಾದಂತವು; ಕಸುವಿರುವಂತವು; ಧೀರ್ಥಕಾಲ ಪರಿಣಾಮ\n\nಬೀರುವಂತವ; ಮತ್ತೆಮತ್ತೆ ಮನ ಸೆಳೆಯುವಂತವು.\n\nಈ ಶ್ಲೋಕದಲ್ಲಿ ಕೃಷ್ಣ ಸಾತ್ವಿಕ ಆಹಾರದ ಬಗ್ಗೆ ವಿವರಿಸಿದ್ದಾನೆ. ಯಾವ ಆಹಾರ ನಮ್ಮ ಆಯಸ್ಸಿನ ವೃದ್ಧಿಗೆ\nಪೂರಕವೋ; ಯಾವ ಆಹಾರ ನಮಗೆ ಸೌಮ್ಯ ಸ್ವಭಾವವನ್ನು ಕೊಡುತ್ತದೋ; ಯಾವ ಆಹಾರ ದೇಹಕ್ಕೆ\n\nಪೌಷ್ಟಿಕಾಂಶವನ್ನು ಕೊಡುತ್ತದೋ; ಯಾವ ಆಹಾರ ಆರೋಗ್ಯವನ್ನು ಕೊಡುತ್ತದೋ ಅಂತಹ ಆಹಾರ ಸಾತ್ವಿಕ\nಆಹಾರ. ಈ ಆಹಾರವನ್ನು ನೋಡಿದಾಗ ನಮಗೆ ಕೆಟ್ಟ ಭಾವನೆ ಬರುವುದಿಲ್ಲ. ಅದು ರಸವತ್ತಾಗಿರುತ್ತದೆ,\nರುಚಿಯಾಗಿರುತ್ತದೆ. ಇದನ್ನು ತಿಂದಾಗ ನಮ್ಮ ಹೊಟ್ಟೆ ತುಂಬುತ್ತದೆ ಮತ್ತು ತಕ್ಷಣ ಹಸಿವೆಯಾಗುವುದಿಲ್ಲ.\nನೋಡಲು ಹೃದಯಂಗಮವಾಗಿರುತ್ತದೆ, ತಿಂದ ನೆನಪು ಉಳಿಯುವಂತಿರುತ್ತದೆ.\n\nನಿಜವಾದ ಸಾತ್ವಿಕರು ಏನು ತಿನ್ನು ತ್ತಾರೋ ಅದು ಸಾತ್ವಿಕ ಆಹಾರವಾಗಿರುತ್ತದೆ. ಪ್ರಕೃತಿ ಸಹಜವಾದ,\nರಸವತ್ತಾದ, ರುಚಿಯಾದ, ಹಣ್ಣು-ಹಂಪಲು, ಗಡ್ಡೆ-ಗೆಣಸು, ಬೇಳೆ-ಕಾಳು, ಕಂದ-ಮೂಲಗಳು ಸಾಮಾನ್ಯವಾಗಿ\nಸಾತ್ವಿಕ ಆಹಾರವಾಗಿರುತ್ತದೆ. ಆಯುಸ್ಸನ್ನು ಹೆಚ್ಚಿಸುವ ಶುದ್ಧ ತುಪ್ಪ(ಮಿತವಾಗಿ ಬಳಸಿದಾಗ) ಸಾತ್ವಿಕ ಆಹಾರ.\n\nಕಟ್ಟಮ್ಸಲವಣಾತ್ಯುಷ್ಟತೀಕ್ಷರೂಕ್ಷವಿದಾಹಿನಃ ।\n\nಆಹಾರಾ ರಾಜಸಸ್ಯೇಷ್ಟಾ ದುಃಖಶೋಕಾಮಯಪ್ರದಾಃ ॥1೯॥\n\nಕಟು ಆಮ್ಲ ಲವಣ ಅತಿ ಉಷ್ಣ ತೀಕ್ಷ ರೂಕ್ಷ ವಿದಾಹಿನಃ ।\n\nಆಹಾರಾಃ ರಾಜಸಸ್ಯ ಇಷ್ಟಾಃ ದುಃಖ ಶೋಕ ಆಮಯ ಪ್ರದಾಃ -ಇವು ರಾಜಸರಿಗೆ ಮೆಚ್ಚಿಗೆಯಾದ ತಿನಿಸುಗಳು:\nಅತಿಯಾದ ಖಾರ, ಹುಳಿ, ಉಪ್ಪು, ತುಂಬಾ ಬಿಸಿ, ಬಿರುಸು, ನೀರಸ ಮತ್ತು ಉರಿಬರಿಸುವಂತವು; ದುಃಖ-\nದುಮ್ಮಾನ ಮತ್ತು ಖಾಯಿಲೆ ಬರಿಸುವಂತವು.\n\nಇಲ್ಲಿ ರಾಜಸ ಆಹಾರದ ವಿವರಣೆಯನ್ನು ಕೃಷ್ಣ ಕೊಟ್ಟಿದ್ದಾನೆ. ವಿಪರೀತ ಖಾರ, ವಿಪರೀತ ಹುಳಿ, ಅತಿ ಉಪ್ಪು,\nರಾಜಸ ಆಹಾರವೆನಿಸುತ್ತದೆ. ಅತಿಯಾದ ಬಿಸಿಯನ್ನು ಕುಡಿಯುವುದು; ಬಿರುಸು ಮತ್ತು ನೀರಸವಾದ\nಆಹಾರವನ್ನು ಸೇವಿಸುವುದು; ಎದೆ ಸುಡುವ ಆಹಾರ ಸೇವನೆ-ಇವು ರಾಜಸರ ಲಕ್ಷಣವಾಗಿರುತ್ತದೆ. ಈ ಆಹಾರ\nಸೇವನೆಯಿಂದ ಮಾನಸಿಕ ಮತ್ತು ದೈಹಿಕ ವೇದನೆ ಹೆಚ್ಚುತ್ತದೆ. ಇದು ಖಾಯಿಲೆಯನ್ನು ತರಬಲ್ಲ ಆಹಾರ.\n\nಹಸಿಮೆಣಸಿನ ಕಾಯಿಯನ್ನು ನೇರವಾಗಿ ತಿನ್ನುವುದು, ಹುಣಸೇ ಹಣ್ಣನ್ನು ಅತಿಯಾಗಿ ತಿನ್ನುವುದು, ಯಾವಾಗಲೂ\nಹೆಚ್ಚು ಉಪ್ಪನ್ನು ಬಳಸುವುದು, ಗಂಟಲು ಸುಡುವ ಕಾಫಿ ಕುಡಿಯುವುದು, ಅತಿಯಾಗಿ ಸಾಸಿವೆ ಮತ್ತು ಮಸಾಲೆ\nಬಳಸುವುದು, ರಸವಿಲ್ಲದ ಆಹಾರ (tasteless food) ಸೇವನೆ; ಇತ್ಯಾದಿ ರಾಜಸರ ಆಹಾರ ಕ್ರಮಕ್ಕೆ ಕೆಲವು\nಉದಾಹರಣೆಗಳು.[ಒಂದು ವೇಳೆ ಇಲ್ಲಿ ಹೇಳಿದ ಈ ಆಹಾರವನ್ನು ರೋಗ ಪರಿಹಾರಕ್ಕಾಗಿ ವೈದ್ಯರು ಸೂಚಿಸಿದ್ದರೆ\nಅದು ರೋಗಿಗೆ ಸಾತ್ವಿಕ ಆಹಾರವೆನಿಸುತ್ತದೆ].\n",
  "17.10": "ಯಾತಯಾಮಂ ಗತರಸಂ ಪೂತಿ ಪರ್ಯುಷಿತಂ ಚ ಯತ್‌ |\nಉಚ್ಛಿಷ್ಟಮ್‌ ಅಪಿ ಚ ಅಮೇಧ್ಯಂ ಭೋಜನಂ ತಾಮಸ ಪ್ರಿಯಮ್‌ - ಇದು ತಾಮಸರಿಗೆ ಮೆಚ್ಚಿನ ತಿನಿಸು: ಅಟ್ಟು\nಜಾವ ಕಳೆದದ್ದು, ರುಚಿ ಕಳೆದುಕೊಂಡದ್ದು, ಹಳಸಿದ್ದು, ತಂಗಳಾದದ್ದು, ಎಂಜಲು ಮತ್ತು ಕೊಳಕಾದದ್ದು.\n\nತಾಮಸರಿಗೆ ಜೀವನದಲ್ಲಿ ಅತಿದೊಡ್ಡ ಸಂಗತಿ ಎಂದರೆ ಭೋಜನ. ಇವರು ಆಹಾರವನ್ನು ದೇವರಿಗೆ\nಸಮರ್ಪಿಸದೇ ಸೇವನೆ ಮಾಡುತ್ತಾರೆ. ನೀರಸವಾದ, ಹಳಸಿದ, ವಾಸನೆ ಬರುವ, ರುಚಿಗೆಟ್ಟ ಆಹಾರ\nತಾಮಸರಿಗೆ ಇಷ್ಟ. ಇವರು ಎಂಜಲು ಊಟವನ್ನು ಇಷ್ಟಪಡುತ್ತಾರೆ. [ಉದಾಹರಣೆಗೆ ಒಂದೇ ತಟ್ಟೆಯಲ್ಲಿ ಅನೇಕ\nಮಂದಿ ಎಂಜಲು ಹಂಚಿಕೊಂಡು ತಿನ್ನುವುದು].\n\nಹೀಗೆ ಆಹಾರದಿಂದ ಹೇಗೆ ವ್ಯಕ್ತಿಯನ್ನು ಗುರುತಿಸಬಹುದು ಎನ್ನುವ ವಿಧಾನವನ್ನು ವಿವರಿಸಿದ ಕೃಷ್ಣ, ಮುಂದೆ\nನಮ್ಮ ಆಚಾರದಿಂದ(ಯಜ್ಞ, ತಪಸ್ಸು, ದಾನ) ವ್ಯಕ್ತಿಯ ಸ್ವಭಾವವನ್ನು ಅರಿಯುವ ವಿಧಾನವನ್ನು ವಿವರಿಸುತ್ತಾನೆ.\n",
  "17.11": "ಅಫಲ ಆಕಾಂಕ್ಷಿಭಿಃ ಯಜ್ಞಃ ವಿಧಿದೃಷ್ಟೊ ೀಯಃ ಇಜ್ಯತೇ |\nಯಷ್ಟವ್ಯಮ್‌ ಏವ ಇತಿ ಮನಃ ಸಮಾಧಾಯ ಸಃ ಸಾತ್ವಿಕ; -ಶಾಸ್ತ್ರದ ಕಟ್ಟಳೆಗೆ ಸರಿಯಾಗಿ, ಫಲದ ನಂಟಿಲ್ಲದೆ,\nಕರ್ತವ್ಯ ಎನ್ನುವ ಭಾವದಿಂದ ಮನ ಮೆಚ್ಚಿ ಮಾಡುವ ಯಜ್ಞ ಸಾತ್ವಿಕ ಯಜ್ಞ.\n\nಯಜ್ಞ ಮಾಡುವವರೆಲ್ಲಾ ಸಾತ್ವಿಕರಲ್ಲ. ಯಜ್ಞದಲ್ಲೂ ಸಾತ್ವಿಕ ರಾಜಸ ಮತ್ತು ತಾಮಸವೆಂಬ ಮೂರು\nಪ್ರಭೇದವಿದೆ. ಈ ಶ್ಲೋಕದಲ್ಲಿ ಕೃಷ್ಣ ಸಾತ್ವಿಕ ಯಜ್ಞ ಹೇಗಿರುತ್ತದೆ ಎನ್ನುವುದನ್ನು ವಿವರಿಸಿದ್ದಾನೆ. ಯಜ್ಞ ಎಂದರೆ\nಕೇವಲ ಅಗ್ನಿಕುಂಡದಲ್ಲಿ ಮಾಡುವ ಪೂಜೆ ಮಾತ್ರ ಅಲ್ಲ. ಪೀಠದಲ್ಲಿ ಭಗವಂತನನ್ನು ಪೂಜಿಸುವುದೂ ಯಜ್ಞ,\nಮಾನಸಿಕವಾಗಿ ಭಗವಂತನ ಧ್ಯಾನ ಮಾಡುವುದೂ ಯಜ್ಞ. ಯಾವುದೇ ಫಲ ಕಾಮನೆ ಇಲ್ಲದೆ, ದೇವರು\nಪ್ರಸನ್ನನಾಗಲಿ-ಆತನ ದಯಾ ದೃಷ್ಟಿ ನನ್ನ ಮೇಲಿರಲಿ ಎಂದು, ವಿಧಿಪೂರ್ವಕವಾಗಿ ಮಾಡುವ ಪೂಜೆ ಸಾತ್ವಿಕ\nಯಜ್ಞವೆನಿಸುತ್ತದೆ. ಯಾಂತ್ರಿಕವಾಗಿ, ಮಂತ್ರದ ಅರ್ಥ ಗೊತ್ತಿಲ್ಲದೆ, ಯಾವುದೋ ಸಂಕುಚಿತ ಫಲಾಪೇಕ್ಷೆಯಿಂದ\n\nಇ ಎಂ\n\nಪೂಜೆ ಮಾಡಿದರೆ ಅದು ಸಾತ್ವಿಕ ಯಜ್ಞವಾಗುವುದಿಲ್ಲ.\n\nಇಲ್ಲಿ 'ವಿಧಿಪೂರ್ವಕವಾಗಿ' ಎಂದು ಹೇಳಲಾಗಿದೆ. ಇದು ಬಹಳ ಮುಖ್ಯವಾದ ವಿಚಾರ. ಉದಾಹರಣೆಗೆ ನಾವು\nಪೂಜೆ ಮಾಡುವಾಗ ಘಂಟಾನಾದ ಮಾಡುತ್ತೇವೆ; ಶಂಖನಾದ ಮಾಡುತ್ತೇವೆ. ಈ ರೀತಿ ಯಾವುದೇ ಪೂಜಾ\nವಿಧಾನವಿದ್ದರೂ ಕೂಡಾ, ಅದನ್ನು ಮಾಡುವ ಮೊದಲು ಏಕೆ ಮಾಡುತ್ತಿದ್ದೇವೆ ಎನ್ನು ವ ತಿಳುವಳಿಕೆ ನಮಗೆ\n\nಅಗತ್ಯ. ಘಂಟೆಯನ್ನು ಗಣಗಣ ಎಂದು ಕರ್ಕಶವಾಗಿ ಒಂದೇ ಸಮನೆ ಬಾರಿಸಬಾರದು. ಘಂಟಾನಾದ\nಮಾಡುವಾಗ ಅದರಿಂದ ಓಂಕಾರನಾದ ಹೊರ ಹೊಮಬೇಕು. ಈ ರೀತಿ ಓಂಕಾರ ನಾದ ಹೊರಹೊಮ್ಮಿದಾಗ-\nಆ ನಾದ ಕೇಳಿಸುವ ಪ್ರದೇಶದಲ್ಲಿರುವ ಎಲ್ಲಾ ದುಷ್ಟ ಶಕ್ತಿಗಳೂ ಅಲ್ಲಿಂದ ಓಡಿ ಹೋಗುತ್ತವೆ ಮತ್ತು ಈ ನಾದ\nದೇವತಾ ಶಕ್ತಿಗಳನ್ನು ಆಕರ್ಷಿಸುತ್ತದೆ. ಇದರಿಂದ ಪೂಜೆಗೆ ಬೇಕಾದ ಶುಭ್ರ ವಾತಾವರಣ ನಿರ್ಮಾಣವಾಗುತ್ತದೆ.\nಇಲ್ಲಿ ಮನಃಪೂರ್ವಕವಾಗಿ ದುಷ್ಟಶಕ್ತಿಗಳು ಹೋಗಲಿ, ದೇವತಾಶಕ್ತಿಗಳು ಬರಲಿ ಎಂದು ಪ್ರಾರ್ಥಿಸಿ, ಘಂಟೆಯಿಂದ\nಓಂಕಾರನಾದ ತೆಗೆಯುವುದು ಬಹಳ ಮುಖ್ಯ. ಘಂಟೆಯಿಂದ ಎಂದೂ ಅಪಸ್ವರ ಬರಬಾರದು. ಘಂಟಾನಾದಕ್ಕೆ\nಒಂದು ಶ್ರುತಿ ಇದೆ. ಸಪ್ತ ಸ್ವರಗಳಿಗೆ ಸಪ್ತ ಸ್ವರದ ಘಂಟೆಗಳಿವೆ. ಅದನ್ನು ಶ್ರುತಿಬದ್ಧವಾಗಿ ಬಾರಿಸಬೇಕು. ಇದು\nಓಂಕಾರದಿಂದ ವಾತಾವರಣ ಶುದ್ಧಿ ಮಾಡುವ ಅದ್ಭುತ ಪ್ರಕ್ರಿಯೆ. ಇದು ಕೇವಲ ಒಂದು ಉದಾಹರಣೆಯಷ್ಟೆ.\nಹೀಗೆ ನಾವು ನಮ್ಮ ಪ್ರತಿಯೊಂದು ಕ್ರಿಯೆಯನ್ನು ತಿಳಿದು ಮನಃಪೂರ್ವಕವಾಗಿ ಮಾಡಬೇಕು; ಮಾಡುವ\nಕ್ರಿಯೆಯಲ್ಲಿ ನಮಗೆ ಖುಷಿ ಇರಬೇಕು. ಹೀಗೆ ಮಾಡಿದಾಗ ಮಾತ್ರ ಅದು ಸಾತ್ವಿಕ ಯಜ್ಞ ಎನಿಸುತ್ತದೆ.",
  "17.12": "ಅಭಿಸಂಧಾಯ ತು ಫಲಮ್‌ ಡಂಭ ಅರ್ಥಮ್‌ ಅಪಿ ಚ ಏವ ಯತ್‌ |\nಇಜ್ಯತೇ ಭರತಶ್ರೇಷ್ಠ ತಮ್‌ ಯಜ್ಞಂ ವಿದ್ಧಿ ರಾಜಸಮ್‌ -ಓ ಭರತಶ್ರೇಷ್ಠಾ, ಫಲದ ಬಯಕೆಯಿಂದ ಅಥವಾ\nಬೂಟಾಟಿಕೆಗಾಗಿ ಮಾಡುವ ಯಜ್ಞ ರಾಜಸವೆಂದು ತಿಳಿ.\n\nಸ್ವಾರ್ಥದಿಂದ ಒಂದು ವಿಶೇಷ ಫಲವನ್ನು ಬಯಸಿ, ಡಂಭಾಚಾರದಿಂದ ಮಾಡುವ ಯಜ್ಞ ರಾಜಸ ಯಜ್ಞ\nಎನಿಸುತ್ತದೆ. ಯಾವುದೇ ಯಜ್ಞ ಭಗವಂತನನ್ನು ಸೇರಬೇಕಾದರೆ ಅದನ್ನು ನಾವು ಭಕ್ತಿಯಿಂದ ಮಾಡಬೇಕು.\nಭಗವಂತನಲ್ಲಿ ರತರಾದವರಲ್ಲಿ ನಾವು ಶ್ರೇಷ್ಠರಾಗಿ(ಭರತಶ್ರೇಷ್ಠ) ಕ್ರಿಯೆ ಮಾಡಬೇಕು. ಇದಿಲ್ಲದೇ ಪ್ರಚಾರಕ್ಕಾಗಿ\nಮಾಡುವ ಯಜ್ಞ ರಾಜಸ ಯಜ್ಞವಾಗುತ್ತದೆ.",
  "17.13": "ವಿಧಿಹೀನಮ್‌ ಅಸೃಷ್ಟ ಅನ್ನಮ್‌ ಮಂತ್ರ ಹೀನಮ್‌ ಅದಕ್ಷಿಣಮ್‌।\nಶ್ರದ್ಧಾ ವಿರಹಿತಂ ಯಜ್ಞಂ ತಾಮಸಂ ಪರಿಚಕ್ಷತೇ ಶಾಸ್ತ್ರಕ್ಕೆ ಅನುಗುಣವಾಗಿಲ್ಲ; ಅನ್ನ ದಾನವಿಲ್ಲ; ಮಂತ್ರವಿಲ್ಲ;\nದಕ್ಷಿಣೆಯಿಲ್ಲ; ಮಾಡುವ ಕ್ರಿಯೆಯಲ್ಲಿ ನಂಬಿಕೆಯೂ ಇಲ್ಲ. ಇಂತಹ ಯಜ್ಞವನ್ನು ತಾಮಸ ಎನ್ನುತ್ತಾರೆ.\n\nಮಂತ್ರ ಸರಿಯಾಗಿ ಹೇಳದೇ ಇರುವುದು, ಮಂತ್ರವನ್ನು ಕ್ರಮ ತಪ್ಪಿ ಹೇಳುವುದು, ಪದ ಉಚ್ಛಾರ\nಸರಿಯಾಗಿಲ್ಲದೇ ಇರುವುದು-ಇವೆಲ್ಲವೂ ವಿಧಿಹೀನ. ಈ ರೀತಿ ಮಾಡುವ ಯಜ್ಞ ತಾಮಸ ಯಜ್ಞ. ಯಾವುದೇ\nಯಜ್ಞದಲ್ಲಿ ಹೇಗೆ ಪ್ರತಿಮೆಯ ಮೂಲಕ ಮತ್ತು ಅಗ್ನಿಯ ಮೂಲಕ ಆರಾಧನೆ ನಡೆಯುತ್ತದೆಯೋ, ಅದೇ ರೀತಿ\nಚರಮೂರ್ತಿಗಳ ಆರಾಧನೆ ಬಹಳ ಮುಖ್ಯ. ಅನ್ನದಾನ ಮಾಡುವ ಮೂಲಕ ಪ್ರತಿಯೊಬ್ಬರೊಳಗೂ ಇರುವ\nಭಗವಂತನ ಆರಾಧನೆ ಈ ಚರಮೂರ್ತಿ ಆರಾಧನೆ. ಹೀಗೆ ಅನ್ನದಾನವಿಲ್ಲದೆ, ದಕ್ಷಿಣೆ(ವೈದಿಕರಿಗೆ ಅವರ ಜೀವನ\nನಿರ್ವಾಹಣೆಗಾಗಿ ನಾವು ಸಲ್ಲಿಸುವ ಸೇವೆ) ಇಲ್ಲದೆ ಮಾಡುವ ಯಜ್ಞ ತಾಮಸ ಯಜ್ಞ. ಇವೆಲ್ಲವುದಕ್ಕಿಂತ\nಮುಖ್ಯವಾದುದು ಶ್ರದ್ಧೆ. ಭಗವಂತನ ಮೇಲೆ ಅಚಲವಾದ ಶ್ರೇಷ್ಠ ಶ್ರದ್ಧೆ ಇಲ್ಲದೇ ಮಾಡುವ ಯಾವುದೇ\nಯಜ್ಞವಿರಲಿ-ಅದು ಸರ್ವತ್ರ ತಾಮಸ ಯಜ್ಞವಾಗುತ್ತದೆ.\n\nಆಹಾರ ಮತ್ತು ಯಜ್ಞದ ನಂತರ ಕೃಷ್ಣ ಮುಂದಿನ ಶ್ಲೋಕಗಳಲ್ಲಿ ಮೂರು ವಿಧದ ತಪಸ್ಸಿನ ಬಗ್ಗೆ ವಿವರಿಸುತ್ತಾನೆ.\nಮೂಲಭೂತವಾಗಿ ತಪಸ್ಸಿನಲ್ಲಿ ಮೂರು ವಿಧ. ನಮ್ಮ ನಡೆಯಲ್ಲಿ ಶಿಸ್ತುಬದ್ಧತೆಯನ್ನು ತರುವುದು-ತಪಸ್ಸು;\nಆಳವಾದ ಚಿಂತನೆ-ತಪಸ್ಸು; ಮನಃಶುದ್ಧಿಗಾಗಿ ಮಾಡುವ ದೇಹದಂಡನೆಯೂ-ತಪಸ್ಸು. ತಪಸ್ಸು ಮಾಡಲು\nಕಾಡಿಗೆ ಹೋಗಬೇಕಾಗಿಲ್ಲ. ಮನೆಯಲ್ಲೇ ಇದ್ದು ತಪಸ್ಸು ಮಾಡಬಹುದು. ಸಾತ್ವಿಕ, ರಾಜಸ ಮತ್ತು ತಾಮಸ\nತಪಸ್ಸನ್ನು ವಿವರಿಸುವ ಮೊದಲು ಇಲ್ಲಿ ಕೃಷ್ಣ ಶರೀರ, ಮಾತು ಮತ್ತು ಮನ ಎನ್ನುವ ಮೂಲಭೂತವಾದ ಮೂರು\nತಪಸ್ಸಿನ ವಿವರಣೆಯನ್ನು ಮುಂದಿನ ಮೂರು ಶ್ಲೋಕಗಳಲ್ಲಿ ಕೊಡುತ್ತಾನೆ.",
  "17.14": "ದೇವ ದ್ವಿಜ ಗುರು ಪ್ರಾಜ್ಞ ಪೂಜನಂ ಶೌಚಮ್‌ ಆರ್ಜವಮ್‌ |\n\nಬ್ರಹ್ಮಚರ್ಯಮ್‌ ಅಹಿಂಸಾ ಚ ಶಾರೀರಂ ತಪಃ ಉಚ್ಯತೇ -ದೇವತೆಗಳನ್ನು , ಅರಿವಿನಿಂದ ಮರುಹುಟ್ಟು\nಪಡೆದವರನ್ನು, ಗುರುಗಳನ್ನು ಮತ್ತು ತುಂಬಾ ತಿಳಿದವರನ್ನು ಗೌರವಿಸುವುದು, ನೈರ್ಮಲ್ಯ, ನೇರ ನಡೆ,\nಬ್ರಹ್ಮಚರ್ಯ ಮತ್ತು ಇನ್ನೊಬ್ಬರಿಗೆ ಕಾಟ ನೀಡದಿರುವುದು ಶರೀರದ ತಪಸ್ಸು ಎನಿಸುತ್ತದೆ.\n\nದೇವರ ಪ್ರತೀಕ ಎಲ್ಲಿ ಕಂಡಿತೋ ಅಲ್ಲಿ ತಲೆಬಾಗುವುದು; ಜ್ಞಾನಿಗಳಿಗೆ ಗೌರವ ಕೊಡುವುದು; ಗುರುವಿಗೆ\nತಲೆಬಾಗುವುದು; ಭಗವದ್ಭೂತಿಯಿಂದ ಭಗವಂತನನ್ನು ಅನುಭವಿಸಿದ ಅನುಭಾವಿಗಳಾದ ಪ್ರಾಜ್ಞರನ್ನು\nಗೌರವಿಸುವುದು- ಇವೆಲ್ಲವೂ ಶರೀರ ತಪಸ್ಸು ಎನಿಸುತ್ತದೆ. ಇದರ ಜೊತೆಗೆ ಶುಚಿತ್ವವನ್ನು ಕಾಪಾಡಿಕೊಂಡು\nಬದುಕುವುದು, ನೇರ ನಡೆ-ನುಡಿ, ಬ್ರಹ್ಮಚರ್ಯ ಪಾಲನೆ. ಹಾಗೂ ಇನ್ನೊಬ್ಬರಿಗೆ. ನಮ್ಮಿಂದ\nತೊಂದರೆಯಾಗದಂತೆ ಬದುಕುವುದು ಶರೀರದ ತಪಸ್ಸು. [ಈ ಶ್ಲೋಕದಲ್ಲಿ ಹೇಳಿರುವ ಶೌಚಮ್‌, ಆರ್ಜವಮ್‌\nಮತ್ತು ಅಹಿಂಸಾ-ಈ ಗುಣಗಳ ಪೂರ್ಣ ವಿವರಣೆಯನ್ನು ಹದಿನಾರನೇ ಅಧ್ಯಾಯದ ಪ್ರಾರಂಭಿಕ ಶ್ಲೋಕದಲ್ಲಿ\nವಿವರಿಸಲಾಗಿದೆ]. ಇಲ್ಲಿ ಬ್ರಹ್ಮಚರ್ಯ ಪಾಲನೆ' ಅಂದರೆ ಮನಸ್ಸನ್ನು ಭಗವಂತನಲ್ಲಿ ನೆಲೆಗೊಳಿಸುವುದು; ಅದಕ್ಕೆ\n\nಪೂರಕವಾಗಿ ವೇದಾಧ್ಯಯನ ಮಾಡುವುದು ಹಾಗೂ ಅಧ್ಯಯನಕ್ಕೆ ಪೂರಕವಾಗಿ ದೈಹಿಕ ಬ್ರಹ್ಮಚರ್ಯ ಪಾಲನೆ.\nದೈಹಿಕವಾಗಿ ಪೂರ್ಣ ಬ್ರಹ್ಮಚರ್ಯ ಕೇವಲ ಸನ್ಯಾಸಿಗಳಿಗೆ ಮತ್ತು ಬ್ರಹ್ಮಚಾರಿಗಳಿಗೆ ಅನ್ವಯಿಸುತ್ತದೆ.\nಗ್ರಹಸ್ಥರಾದವರು ಈ ರೀತಿ ಬದುಕಲು ಸಾಧ್ಯವಿಲ್ಲ. ಆದ್ದರಿಂದ ಗ್ರಹಸ್ಥರಲ್ಲಿ ಬ್ರಹ್ಮಚರ್ಯ ಪಾಲನೆ ಎಂದರೆ-\nಅವರು ಸ್ವಚ್ಛಂದ ಕಾಮಿಗಳಾಗದೇ, ಗ್ರಹಸ್ಥಧರ್ಮ ಪಾಲನೆಯ ಆವರಣದಲ್ಲಿ ಬದುಕುವುದು ಎಂದರ್ಥ. ಹೀಗೆ\nಭಗವಂತನಲ್ಲಿ ಶರಣಾಗತಿ; ಜ್ಞಾನಿಗಳಿಗೆ, ಗುರುಗಳಿಗೆ, ಪ್ರಾಜ್ಞರಿಗೆ ಗೌರವ ಕೊಡುವುದು, ಶುಚಿತ್ವವನ್ನು\nಕಾಪಾಡಿಕೊಳ್ಳುವುದು, ನೇರ ನಡೆ ನುಡಿ, ಬ್ರಹ್ಮಚರ್ಯ ಪಾಲನೆ ಮತ್ತು ಅಹಿಂಸೆಯಿಂದ ಬದುಕುವುದು-\nಶಾರೀರಿಕ ತಪಸ್ಸು . ನಾವು. ಸಾಮಾಜಿಕವಾಗಿ ಸಭ್ಯರಾಗಿ ಬದುಕಲು ಈ ತಪಸ್ಸು ಬೇಕೇಬೇಕು.\nಮನುಷ್ಯನಾದವನು ಅನುಸರಿಸಬೇಕಾದ ದೈಹಿಕ ನೀತಿಗಳಿವು\n",
  "17.15": "ಅನುದ್ವೇಗ ಕರಂ ವಾಕ್ಯಂ ಸತ್ಯಂ ಪ್ರಿಯ ಹಿತಂ ಚ ಯತ್‌ ।\nಸ್ವಾಧ್ಯಾಯ ಅಭ್ಯಸನಂ ಚ ಏವ ವಾಜ್ಮಯಂ ತಪಃ ಉಚ್ಯತೇ-ಕೆರಳಿಸದ, ದಿಟವಾದ, ಕೇಳುವುದಕ್ಕೆ ಮೆಚ್ಚಾದ\nಹಾಗೂ ಬಾಳಿಗೆ ಒಳಿತಾದ ಮಾತು ಮತ್ತು ಶಾಸ್ತ್ರಗಳ ಓದು ಮಾತಿನ ತಪಸ್ಸು ಎನಿಸುತ್ತದೆ.\n\nಹಿಂದಿನ ಅಧ್ಯಾಯದಲ್ಲಿ ವಿಶ್ಲೇಶಿಸಿದಂತೆ ಇದ್ದದ್ದನ್ನು ಇದ್ದಂತೆ ಹೇಳುವುದೇ ಸತ್ಯವಲ್ಲ. ಸತ್ಯ ಅಂದರೆ ಏನು\nಎನ್ನುವ ವಿವರಣೆಯನ್ನು ಕೃಷ್ಣ ಈ ಶ್ಲೋಕದ ಮೂಲಕ ನಮಗೆ ಕೊಟ್ಟಿದ್ದಾನೆ. ಎಲ್ಲಿ ನಿಜವಾದ ಸಜ್ಜನಿಕೆ ಇದೇ-\nಅದನ್ನು ಮೆಚ್ಚಿಕೊಂಡು, ಅದಕ್ಕೆ ಪೂರಕವಾಗಿ, ಇನ್ನೊಬ್ಬರನ್ನು ನೋಯಿಸದೆ, ಅವರಿಗೆ ಹಿತವಾಗುವ ರೀತಿ\nಮಾತನಾಡುವುದು ಮಾತಿನ ತಪಸ್ಸು. ಇನ್ನೊಬ್ಬರಿಗೆ ಪ್ರಿಯವೂ-ಹಿತವೂ ಆದ ಮಾತನ್ನು ಆಡುವುದು ಬಹಳ\nಕಷ್ಟ. ಏಕೆಂದರೆ ಹೆಚ್ಚಿನ ಸಂದರ್ಭದಲ್ಲಿ ಪ್ರಿಯವಾದದ್ದು ಹಿತವಾಗಿರುವುದಿಲ್ಲ. ಇಂತಹ ಸಂದರ್ಭದಲ್ಲಿ ಮೌನ\nಲೇಸು. ಕೃಷ್ಣನ ಕಥೆಯನ್ನು ಓದುವಾಗ ಅನೇಕ ಕಡೆ ನಮಗೆ ಕೃಷ್ಣ ಸುಳ್ಳು ಹೇಳಿದಂತೆ, ಮೋಸ ಮಾಡಿದಂತೆ\nಕಾಣಿಸುತ್ತದೆ. ಆದರೆ ಆ ಕ್ರಿಯೆಯ ಹಿಂದೆ ಇರುವ ಕಾರುಣ್ಯ, ಹಿತಚಿಂತನೆಯನ್ನು ಗಮನಿಸಿದಾಗ ನಮಗೆ ಅದು\nಸುಳ್ಳಲ್ಲ ಎನ್ನುವುದು ತಿಳಿಯುತ್ತದೆ. ದೈನಂದಿನ ಜೀವನದಲ್ಲಿ ನಾವು ಮಾತನಾಡುವಾಗ ನಮಗೆ ಕೃಷ್ಣ ಈ\nಶ್ಲೋಕದಲ್ಲಿ ಹೇಳಿದ ಸಂದೇಶದ ಎಚ್ಚರವಿರಬೇಕು. ಮಾತನಾಡದೆ ಮೌನವಾಗಿದ್ದರೂ ಸರಿ-ಆದರೆ ಏನೋ\nಮಾತನಾಡಿ ಆನಂತರ ಪಶ್ಚಾತ್ತಾಪಪಟ್ಟರೆ ಉಪಯೋಗವಿಲ್ಲ. “ಆಡಿದ ಮಾತನ್ನು ಹಿಂದೆ ಪಡೆಯಲು\nಸಾಧ್ಯವಿಲ್ಲ; ಘಾಸಿಯಾದ ಮನಸ್ಸನ್ನು ವಾಸಿಮಾಡುವ ಮದ್ದು ನಮ್ಮಲ್ಜಿಲ್ಲ”. ಆದ್ದರಿಂದ ಇನ್ನೊಬ್ಬರನ್ನು\nನೋಯಿಸುವ ಮಾತನ್ನೆಂದೂ ಆಡಬೇಡ. ಹಾಳು ಹರಟೆಯಲ್ಲಿ ದಿನ ಕಳೆಯದೆ, ವೇದದ ಅರ್ಥಚಿಂತನೆ,\nಗೀತಾಚಿಂತನೆ, ವಿಷ್ಣುಸಹಸ್ರನಾಮ ಪಠಣ, ಇತ್ಯಾದಿ ಸ್ವಾಧ್ಯಾಯದಲ್ಲಿ ನಿರತನಾಗುವುದು ಮಾತಿನ ತಪಸ್ಸು.",
  "17.16": "ಮನಃ ಪ್ರಸಾದಃ ಸೌಮ್ಯತ್ವಂ ಮೌನಮ್‌ ಆತ್ಮವಿನಿಗ್ರಹಃ ।\nಭಾವಸಂಶುದ್ದಿಃ ಇತಿ ಏತತ್‌ ತಪಃ ಮಾನಸಮ್‌ ಉಚ್ಯತೇ -- ಬಗೆಯ ತಿಳಿ, ಮಿದುತನ, ಮನನ, ತನ್ನ ಮೇಲೆ\nಹಿಡಿತ ಮತ್ತು ಒಳ್ಳೆಯದನ್ನೇ ಬಗೆಯುವುದು-ಇದು ಮನದ ತಪಸ್ಸು ಎನಿಸುತ್ತದೆ.\n\nಮೇಲೆ ಹೇಳಿದ ಎರಡು ವಿಧದ ತಪಸ್ಸಿಗೆ ಮಿಗಿಲಾಗಿರುವ ಮಹಾ ತಪಸ್ಸು ಎಂದರೆ ಮನದ ತಪಸ್ಸು. ಶರೀರ\nಮತ್ತು ಮಾತಿನ ತಪಸ್ಸು ಮನದ ತಪಸ್ಸಿಗೆ ಪೂರಕ. ನಮ್ಮ ಮನಸ್ಸು ಯಾವಾಗಲೂ ಪ್ರಸನ್ನವಾಗಿರಬೇಕು.\nಅದರಲ್ಲಿ ಕೆಟ್ಟ ವಿಚಾರ ತುಂಬಿ. ಕಲುಪಿತವಾಗಿರಬಾರದು. ಅದು ಸೌಮ್ಯವಾಗಿರಬೇಕು, ಅಲ್ಲಿ\nಕ್ರೌರ್ಯವಿರಬಾರದು. ಯಾವುದೇ ಒಂದು ವಿಷಯದ ಮೇಲೆ ತೀರ್ಮಾನಕ್ಕೆ ಬರುವ ಮೊದಲು ಆಳವಾದ\nಚಿಂತನೆ ಮಾಡಬೇಕು. ಒಂದು ವಿಷಯದ ಮೇಲೆ, ಒಬ್ಬ ವ್ಯಕ್ತಿಯ ಮೇಲೆ ದುಡುಕಿ ಪ್ರತಿಕ್ರಿಯಿಸಬಾರದು. ಮನನ\nಮಾಡು, ಮನನ ಮಾಡಿ ಮಾತನಾಡು. ಈ ರೀತಿ ಮನನ ಮಾಡಬೇಕಾದರೆ ನಾವು ಆತ್ಮವಿನಿಗ್ರಹವನ್ನು\nಸಾಧಿಸಬೇಕು( ಹೆಚ್ಚಿನ ವಿವರಕ್ಕಾಗಿ ಅ-೧೩, ಶ್ಲೋ-೭-ನೋಡಿ). ಸ್ವಚ್ಛವಾದ ಕ್ರೌರ್ಯವಿಲ್ಲದ ಮನಸ್ಸಿಗೆ\nಇಂದ್ರಿಯಗಳ ಹಿಡಿತವಿರುತ್ತದೆ. ಅಂತಹ ಮನಸ್ಸಿಗೆ ಕೆಟ್ಟ ಭಾವನೆ ಹೊಳೆಯುವುದಿಲ್ಲ. ಒಬ್ಬರು ನಮ್ಮ ಬಗ್ಗೆ\nಕೆಟ್ಟದ್ದಾಗಿ ಮಾತನಾಡಿದರೂ ಕೂಡಾ ನಮಗೆ ಅವರ ಮೇಲೆ ದ್ವೇಷ, ಕೋಪ ಬರುವುದಿಲ್ಲ. ಈ ರೀತಿ ಮನಸ್ಸಿನ\nನಿಯಂತ್ರಣ ಮಾಡುವುದೇ ಮನಸ್ಸಿನ ತಪಸ್ಸು.\n\nಇಲ್ಲಿ ಹೇಳಿದ ಮೂರು ವಿಧದ ತಪಸ್ಸಿನಲ್ಲಿ ಮತ್ತೆ ಪ್ರತಿಯೊಂದರಲ್ಲೂ ಮೂರು ವಿಧ. ಸಾತ್ವಿಕ, ರಾಜಸ ಮತ್ತು\nತಾಮಸ. ಇದರ ವಿವರಣೆ ಮುಂದಿನ ಮೂರು ಶ್ಲೋಕದಲ್ಲಿದೆ.",
  "17.17": "ಶ್ರದ್ಧಯಾ ಪರಯಾ ತಪ್ಪಂ ತಪಃ ತತ್‌ ತ್ರಿವಿಧಂ ನರೈಃ |\nಅಫಲ ಆಕಾಂಕ್ಷಿಭಿಃ ಯುಕ್ತೆಃ ಸಾತ್ವಿಕಂ ಪರಿಚಕ್ಷತೇ -ಈ ಮೂರೂ ಬಗೆಯ ತಪಸ್ಸನ್ನು ತುಂಬು ನಂಬಿಕೆಯಿಂದ,\nಫಲದ ಬಯಕೆಯಿಲ್ಲದೆ, ಭಗವದರ್ಪಣಭಾವದಿಂದ ಆಚರಿಸಿದಾಗ ಅದನ್ನು ಸಾತ್ವಿಕ ತಪಸ್ಸು ಎನ್ನುತ್ತಾರೆ.\n\nತಪಸ್ಸಿನ ಹಿಂದೆ ಶ್ರೇಷ್ಠವಾದ ಶ್ರದ್ಧೆ-ಪ್ರಾಮಾಣಿಕತೆ ಇದ್ದರೆ ಅದು ಸಾತ್ವಿಕ ತಪಸ್ಸಾಗುತ್ತದೆ. ಭಗವಂತನ\nಪಾರಮ್ಯದ ಎಚ್ಚರದಿಂದ, ಭಗವಂತ ಪ್ರೀತನಾಗಲಿ ಎನ್ನುವ ಅನುಸಂಧಾನದಿಂದ ಮಾಡುವ ಪ್ರತಿಯೊಂದು\nಕ್ರಿಯೆ-ಸಾತ್ವಿಕ ಕ್ರಿಯೆ. ಎನಿಸುತ್ತದೆ. ಉದಾಹರಣೆಗೆ ಗುರುವಿಗೆ ನಮಸ್ಕರಿಸುವಾಗ ಆ ಗುರುವಿನ\nಅಂತರ್ಗತನಾಗಿರುವ ಭಗವಂತನಿಗೆ ನಮಸ್ಕರಿಸುತ್ತಿದ್ದೇನೆ ಎನ್ನುವ ಅನುಸಂಧಾನ. ಹೀಗೆ ನಮ್ಮ ಪ್ರತಿಯೊಂದು\n\nಕ್ರಿಯೆಯ ಹಿಂದೆ ಭಗವದರ್ಪಣ ಬುದ್ಧಿ ಇರಬೇಕು. ಮಂತ್ರಗಳು ಹೇಳುವುದೂ ಇದನ್ನೇ . “ಅನೇನ ಭಗವಾನ್‌\nಗೋಪಾಲಕೃಷ್ಣ ಪ್ರಿಯತಃ-ಶ್ರೀ ಕೃಷ್ಣಾರ್ಪಣ ಮಸ್ತು” ಎಂದು ಹೇಳುವಾಗ ನಮ್ಮಲ್ಲಿ ಕೂಡಾ ಪೂರ್ಣ ಅರ್ಪಣಾ\nಭಾವ ತುಂಬಿರಬೇಕು. ಇಂತಹ ತಪಸ್ಸು ಸಾತ್ವಿಕ ತಪಸ್ಸೆನಿಸುತ್ತದೆ.\n",
  "17.18": "ಸತ್‌ ಕಾರ ಮಾನ ಪೂಜಾ ಅರ್ಥಂ ತಪಃ ಡಂಭೇನ ಚ ಏವ ಯತ್‌ ।\nಕ್ರಿಯತೇ ತತ್‌ ಇಹ ಪ್ರೋಕ್ತಮ್‌ ರಾಜಸಂ ಚಲಮ್‌ ಅಧ್ರುವಮ್‌ - ಮನ್ನ ಣೆ, ಹೊಗಳಿಕೆ ಮತ್ತು ಗೌರವಗಳಿಗಾಗಿ\nಬೂಟಾಟಿಕೆಯಿಂದ ಆಚರಿಸುವ, ನೆಲೆ ಇಲ್ಲದ, ಬಾಳಿಕೆಯಿಲ್ಲದ ತಪಸ್ಸು ರಾಜಸ ಎನ್ನಿಸುತ್ತದೆ.\n\nಭಗವಂತನ ಅನುಸಂಧಾನವಿಲ್ಲದೆ, ತನಗೆ ಜನ ಸತ್ಕಾರ ಮಾಡಲಿ ಎಂದು ಸನ್ಮಾನದ ಆಸೆಯಿಂದ ಮಾಡುವ\nಎಲ್ಲಾ ತಪಸ್ಸು ರಾಜಸ ತಪಸ್ಸು. ಈ ರೀತಿ ಡಂಭಾಚಾರದಿಂದ ಮಾಡುವ ತಪಸ್ಸು ಪರಲೋಕಕ್ಕೆ ಸಲ್ಲುವುದಿಲ್ಲ.\nಚಪಲದಿಂದ ಮಾಡಿದ ಇಂತಹ ಕಾರ್ಯದ ಫಲ ಇಹದಲ್ಲೂ ಶಾಶ್ವತವಲ್ಲ.\n\nಈ ಶ್ಲೋಕದಲ್ಲಿ ಏವ ಮತ್ತು ಚ-ಕಾರ ಒಟ್ಟಿಗೆ ಬಂದಿದೆ. ಇದು ನಮಗೆ ವಿಶೇಷ ಸಂದೇಶವನ್ನು ಕೊಡುತ್ತದೆ.\nಸತ್ಕಾರಕ್ಕಾಗಿಯೂ, ಮಾನಕ್ಕಾಗಿಯೂ, ಡಂಭಕ್ಕಾಗಿಯೂ ಮಾಡುವ ಕ್ರಿಯೆ ರಾಜಸ ಎನಿಸಿದರೆ ; ಭಗವದರ್ಪಣ\nಬುದ್ಧಿಯಿಂದ ಮಾಡಿ ಬಯಸದೇ ಸತ್ಕಾರ ಬಂದರೆ, ನಾಲ್ಕು ಜನರಿಗೆ ತಿಳುವಳಿಕೆ ಬರಲಿ ಎಂದು ಜ್ಞಾನ ದಾನದ\nಭಾವನೆಯಿಂದ ಪ್ರಚಾರ ಮಾಡಿದರೆ-ಅದು ರಾಜಸವಾಗುವುದಿಲ್ಲ. ಇದನ್ನು ತಿಳಿಸುವುದಕ್ಕೋಸ್ಕರ ಇಲ್ಲಿ ಚ\nಮತ್ತು ಎವಕಾರ ಬಳಸಲಾಗಿದೆ.\n\nಮೂಢಗ್ರಾಹೇಣಾ$ತ್ಮನೋ ಯತ್‌ ಪೀಡಯಾ ಕ್ರಿಯತೇ ತಪಃ |\n\nಪರಸ್ಯೋತ್ಸಾ ದನಾರ್ಥಂ ವಾ ತತ್‌ ತಾಮಸಮುದಾಹೃತಮ್‌ ॥೧೯॥\n\nಮೂಢ ಗ್ರಾಹೇಣ ಆತ್ಮನಃ ಯತ್‌ ಪೀಡಯಾ ಕ್ರಿಯತೇ ತಪಃ |\n\nಪರಸ್ಯ ಉತ್ಸಾದನ ಅರ್ಥಂ ವಾ ತತ್‌ ತಾಮಸಮ್‌ ಉದಾಹೃತಮ್‌ -ದುರಾಗ್ರಹದಿಂದ ತನ್ನ ದೇಹವನ್ನೇ\nದಂಡಿಸುವ ಮೂಲಕ, ಅಥವಾ ಆಗದವರನ್ನು ಮುಗಿಸುವುದಕ್ಕಾಗಿ ಮಾಡುವ ತಪಸ್ಸು ತಾಮಸ ತಪಸ್ಸು\nಎನ್ನಿಸುತ್ತದೆ.\n\nತಪ್ಪು ತಿಳುವಳಿಕೆಯಿಂದ, ಭ್ರಮೆಯಿಂದ, ಪರಮಾತ್ಮನ ಅನುಸಂಧಾನವಿಲ್ಲದೆ, ಇನ್ನೊಬ್ಬರು ಹಾಳಾಗಬೇಕು\nಎನ್ನುವ ಕೆಟ್ಟ ಭಾವನೆಯಿಂದ, ತನ್ನ ದೇಹದೊಳಗಿರುವ ಭಗವಂತನ ಎಚ್ಚರವಿಲ್ಲದೆ, ದೇಹ ದಂಡನೆ\nಮಾಡಿಕೊಂಡು ಮಾಡುವ ತಪಸ್ಸು ತಾಮಸ ತಪಸ್ಸು.\n\nದಾತವ್ಯಮಿತಿ ಯದ್‌ ದಾನಂ ದೀಯತೇಇ",
  "17.19": "ಕಟು ಆಮ್ಲ ಲವಣ ಅತಿ ಉಷ್ಣ ತೀಕ್ಷ ರೂಕ್ಷ ವಿದಾಹಿನಃ ।\n\nಆಹಾರಾಃ ರಾಜಸಸ್ಯ ಇಷ್ಟಾಃ ದುಃಖ ಶೋಕ ಆಮಯ ಪ್ರದಾಃ -ಇವು ರಾಜಸರಿಗೆ ಮೆಚ್ಚಿಗೆಯಾದ ತಿನಿಸುಗಳು:\nಅತಿಯಾದ ಖಾರ, ಹುಳಿ, ಉಪ್ಪು, ತುಂಬಾ ಬಿಸಿ, ಬಿರುಸು, ನೀರಸ ಮತ್ತು ಉರಿಬರಿಸುವಂತವು; ದುಃಖ-\nದುಮ್ಮಾನ ಮತ್ತು ಖಾಯಿಲೆ ಬರಿಸುವಂತವು.\n\nಇಲ್ಲಿ ರಾಜಸ ಆಹಾರದ ವಿವರಣೆಯನ್ನು ಕೃಷ್ಣ ಕೊಟ್ಟಿದ್ದಾನೆ. ವಿಪರೀತ ಖಾರ, ವಿಪರೀತ ಹುಳಿ, ಅತಿ ಉಪ್ಪು,\nರಾಜಸ ಆಹಾರವೆನಿಸುತ್ತದೆ. ಅತಿಯಾದ ಬಿಸಿಯನ್ನು ಕುಡಿಯುವುದು; ಬಿರುಸು ಮತ್ತು ನೀರಸವಾದ\nಆಹಾರವನ್ನು ಸೇವಿಸುವುದು; ಎದೆ ಸುಡುವ ಆಹಾರ ಸೇವನೆ-ಇವು ರಾಜಸರ ಲಕ್ಷಣವಾಗಿರುತ್ತದೆ. ಈ ಆಹಾರ\nಸೇವನೆಯಿಂದ ಮಾನಸಿಕ ಮತ್ತು ದೈಹಿಕ ವೇದನೆ ಹೆಚ್ಚುತ್ತದೆ. ಇದು ಖಾಯಿಲೆಯನ್ನು ತರಬಲ್ಲ ಆಹಾರ.\n\nಹಸಿಮೆಣಸಿನ ಕಾಯಿಯನ್ನು ನೇರವಾಗಿ ತಿನ್ನುವುದು, ಹುಣಸೇ ಹಣ್ಣನ್ನು ಅತಿಯಾಗಿ ತಿನ್ನುವುದು, ಯಾವಾಗಲೂ\nಹೆಚ್ಚು ಉಪ್ಪನ್ನು ಬಳಸುವುದು, ಗಂಟಲು ಸುಡುವ ಕಾಫಿ ಕುಡಿಯುವುದು, ಅತಿಯಾಗಿ ಸಾಸಿವೆ ಮತ್ತು ಮಸಾಲೆ\nಬಳಸುವುದು, ರಸವಿಲ್ಲದ ಆಹಾರ (tasteless food) ಸೇವನೆ; ಇತ್ಯಾದಿ ರಾಜಸರ ಆಹಾರ ಕ್ರಮಕ್ಕೆ ಕೆಲವು\nಉದಾಹರಣೆಗಳು.[ಒಂದು ವೇಳೆ ಇಲ್ಲಿ ಹೇಳಿದ ಈ ಆಹಾರವನ್ನು ರೋಗ ಪರಿಹಾರಕ್ಕಾಗಿ ವೈದ್ಯರು ಸೂಚಿಸಿದ್ದರೆ\nಅದು ರೋಗಿಗೆ ಸಾತ್ವಿಕ ಆಹಾರವೆನಿಸುತ್ತದೆ].\n\nಯಾತಯಾಮಂ ಗತರಸಂ ಪೂತಿ ಪರ್ಯುಷಿತಂ ಚ ಯತ್‌ |\nಉಚ್ಛಿಷ್ಟ ಮಪಿ ಚಾಮೇಧ್ಯಂ ಭೋಜನಂ ತಾಮಸಪ್ರಿಯಮ್‌",
  "17.20": "ದಾತವ್ಯಮ್‌ ಇತಿ ಯತ್‌ ದಾನಮ್‌ ದೀಯತೇ ಅನುಪಕಾರಿಣೇ ।\nದೇಶೇ ಕಾಲೇ ಚ ಪಾತ್ರೇ ಚ ತತ್‌ ದಾನಮ್‌ ಸಾತ್ವಿಕಂ ಸ್ಮೃತಮ್‌ -ಪ್ರತ್ಯುಪಕಾರಕ್ಕಾಗಿ ಅಲ್ಲದೆ ಕರ್ತವ್ಯ\nದೃಷ್ಟಿಯಿಂದ ಕೊಡುವ ದಾನ, ತಕ್ಕ ದೇಶ-ಕಾಲಗಳಲ್ಲಿ ತಕ್ಕ ವ್ಯಕ್ತಿಗೆ ಕೊಡುವ ದಾನ ಸಾತ್ವಿಕ ಎನಿಸುತ್ತದೆ.\n\nಯಾವುದೇ ಪ್ರತ್ಯುಪಕಾರದ ನಿರೀಕ್ಷೆ ಇಲ್ಲದೆ, ಆತ್ಮ ಸಂತೋಷದಿಂದ, ಮನಃಪೂರ್ವಕವಾಗಿ, ಪ್ರೀತಿಯಿಂದ,\nಯೋಗ್ಯವಾದ ವ್ಯಕ್ತಿಗೆ, ಯೋಗ್ಯವಾದ ಕಾಲದಲ್ಲಿ, ಯೋಗ್ಯವಾದ ಸ್ಥಳದಲ್ಲಿ ಕೊಡುವುದು; ನನ್ನ ಕರ್ತವ್ಯ ಅನ್ನುವ\nದೃಷ್ಟಿಯಿಂದ ಕೊಡುವ ದಾನ ಸಾತ್ವಿಕ ದಾನ[[ಹೆಚ್ಚಿನ ವಿವರಣೆ : ಅಧ್ಯಾಯ ಹದಿನಾರು ಆರಂಭಿಕ ಶ್ಲೋಕ].",
  "17.21": "ಯತ್‌ ತು ಪ್ರತ್ಯುಪಕಾರಾರ್ಥಂ ಫಲಮ್‌ ಉದ್ದಿಶ್ಯ ವಾ ಪುನಃ।\nದೀಯತೇ ಚ ಪರಿಕ್ಷಿಷ್ಟ 0 ತತ್‌ ರಾಜಸಮ್‌ ಉದಾಹೃತಮ್‌ -ಪ್ರತ್ಯುಪಕಾರಕ್ಕಾಗಿ ಅಥವಾ ಫಲದ ಅಸೆಯಿಂದ,\nಕೊಡಬೇಕಲ್ಲಾ ಎಂದು ಕೊಡುವ ದಾನ ರಾಜಸ ಎನಿಸುತ್ತದೆ.\n\nಇನ್ನೊಬ್ಬ ರು ನಮಗೆ ಮುಂದೆ ಉಪಕಾರ ಮಾಡಲಿ ಎಂದು ಅಥವಾ ಹಿಂದೆ ಮಾಡಿದ ಉಪಕಾರಕ್ಕೆ ಪ್ರತಿಯಾಗಿ,\nಕೊಡಬೇಕಲ್ಲಾ ಎಂದು ಕೊಡುವುದು. ಕೊಡುವಾಗ ಫಲದ ಬಯಕೆಯಿಂದ ಕೊಡುವುದು ರಾಜಸ ದಾನ.",
  "17.22": "ಅದೇಶ ಕಾಲೇ ಯತ್‌ ದಾನಮ್‌ ಅಪಾತ್ರೇಭ್ಯಃ ಚ ದೀಯತೇ ।\nಅಸತ್‌ ಕೃತಮ್‌ ಅವಜ್ಞಾತಮ್‌ ತತ್‌ ತಾಮಸಮ್‌ ಉದಾಹೃತಮ್‌ - ತಕ್ಕುದಲ್ಲದ ದೇಶ-ಕಾಲದಲ್ಲಿ,\nಅನರ್ಹವ್ಯಕ್ತಿಗಳಿಗೆ ಆದರಿಸದೇ ಹೀಗಳೆದು ನೀಡುವ ದಾನ ತಾಮಸ ಎನಿಸುತ್ತದೆ.\n\nನಮಗೆ ಬೇಡವಾದದ್ದನ್ನು ಇನ್ನೊ ಬ್ಬರಿಗೆ ಸಾಗಹಾಕುವುದಕ್ಕೋಸ್ಕರ ಕೊಡುವುದು; ಯೋಗ್ಯರಲ್ಲದವರಿಗೆ ಬೈದು,\nಹೀಯಾಳಿಸಿ, ಅವಮಾನ ಮಾಡಿ ಕೊಡುವುದು-ತಾಮಸ ದಾನ.\n\nಈವರೆಗೆ ಕೃಷ್ಣ ಹೇಳಿದ ಸಾತ್ವಿಕ ಕರ್ಮದ ಮಹತ್ವವನ್ನು ಹೇಳುವ 'ಅರ್ಥವಾದ' ಈ ಅಧ್ಯಾಯದ ಮುಂದಿನ\nಭಾಗ. 'ಅರ್ಥವಾದ' ಎಂದರೆ ಸಾತ್ವಿಕ ಕರ್ಮದ ಮಹತ್ವಿಕೆಯನ್ನು ಹೇಳುವ ನಿರೂಪಣೆ.\n",
  "17.23": "ಓಂ ತತ್‌ ಸತ್‌ ಇತಿ ನಿರ್ದೇಶಃ ಬ್ರಹ್ಮಣಃ ತ್ರಿವಿಧಃ ಸ್ಮೃತಃ |\n\nಬ್ರಾಹ್ಮಣಾಃ ತೇನ ವೇದಾಃ ಚ ಯಜ್ಞಾಃ ಚ ವಿಹಿತಾಃ ಪುರಾ - ಓಂ [ಪ್ರಪಂಚವನ್ನು ಹೊತ್ತವನು ಮತ್ತು\nಪ್ರಪಂಚದಲ್ಲಿ ತುಂಬಿರುವವನು], ತತ್‌ (ವೇದಗಳ ಮೂಲಕ, ಪರೋಕ್ಷವಾಗಿ ಮಾತ್ರ ತಿಳಿಯಲು\nಸಾಧ್ಯವಾದವನು] ಸತ್‌. [ಎಲ್ಲಾ ಶುಭ ಗುಣಗಳಿಂದ ಪೂರ್ಣನಾದವನು] - ಇವು ಭಗವಂತನ ಮೂರು\nಹೆಸರುಗಳು. ಆ ಭಗವಂತನೇ ವೇದಗಳನ್ನೂ, ವೇದಜ್ಞರನ್ನೂ ಮತ್ತು ಯಜ್ಞಗಳನ್ನೂ ಅಣಿಗೊಳಿಸಿದನು.\n\nಓಂ, ತತ್‌, ಸತ್‌ ಇವು ಮೂರು ಭಗವಂತನ ಹೆಸರುಗಳು. ಭಗವಂತನ ಸ್ಮರಣೆಗಾಗಿ, ಭಗವಂತನನ್ನು\nಕರೆಯುವುದಕ್ಕಾಗಿ ಜ್ಞಾನಿಗಳು ಈ ರೀತಿ ಅನುಸಂಧಾನವನ್ನು ಬಳಕೆಗೆ ತಂದರು. ಭಗವಂತನ ಹೆಸರು ನಮ್ಮ\nಹೆಸರಂತಲ್ಲ. ಆತನ ಹೆಸರು ಆತನ ಗುಣವಾಚಕ ಪದಗಳು. ಓಂ' ಭಗವಂತನಿಗೆ ಮೀಸಲಾದ(Exclusive name)\nಹೆಸರು. ಇದು ಮನುಷ್ಯನ ಒಟ್ಟು ಜೀವನದ ಎಲ್ಲಾ ಮುಖವನ್ನು ಮೂರು ಅಕ್ಷರಗಳಲ್ಲಿ(ಅ, ಉ, ಮ್‌) ಹೇಳುತ್ತದೆ.\nಇಡೀ ಜಗತ್ತು ಯಾರಲ್ಲಿ ಓತವಾಗಿದೆಯೋ, ಇಡೀ ಜಗತ್ತು ಯಾರಲ್ಲಿ ಹೆಣೆದುಕೊಂಡಿದೆಯೋ -ಅವನು ಓಂ'.\nನಾವು ಮಾಡುವ ಸಮಸ್ತ ಕರ್ಮವೂ ಅವನಲ್ಲಿ ಅರ್ಪಿತವಾಗಿದೆ ಎಂದು ಹೇಳುವುದಕ್ಕಾಗಿ ಓಂಕಾರವನ್ನು\nಬಳಸುತ್ತಾರೆ. 'ಹರಿಃ ಓಂ' ಎಂದು ಪ್ರಾರಂಭದಲ್ಲಿ ಹೇಳಿದರೆ - “ನಾನು ಮುಂದೆ ಮಾಡತಕ್ಕ ಸಮಸ್ತವೂ\nಭಗವಂತನಿಗೆ ಅರ್ಪಿತವಾಗಿದೆ” ಎಂದು ಹೇಳಿದಂತೆ. [ಓಂಕಾರದ ಬಗ್ಗೆ ಹೆಚ್ಚಿನ ವಿವರಣೆಗಾಗಿ ಅಧ್ಯಾಯ-೭\nಶ್ಲೋಕ ೮-೯ ನೋಡಿ).\n\n'ತತಃ' ಅಂದರೆ ತುಂಬಿರುವವನು. ಭಗವಂತ ಸಮಸ್ತ ಗುಣಗಳ ನೆಲೆ. ಗುಣಪರಿಪೂರ್ಣನಾದ ಅವನು ಸಮಸ್ತ\nವೇದದಲ್ಲಿ ತುಂಬಿದ್ದಾನೆ. ಆದ್ದರಿಂದ ಆತ “ತತ್‌'. ಇನ್ನು “ಸತ್‌ “ ಎಂದರೆ ಯಾವ ದೋಷವೂ ಇಲ್ಲದವ. ಹೀಗೆ\nಓಂ-ತತ್‌-ಸತ್‌ ಎನ್ನುವುದು ವೇದಕಾಲದ ನಾಮತ್ರಯಗಳು. ಇಂದು ನಾವು ಹೇಳುವ ಅಚ್ಯುತಾಯನಮ;,\nಅನಂತಾಯನಮಃ, ಗೋವಿಂದಾಯ ನಮಃ ಕೂಡಾ ಇದೇ ಅರ್ಥವನ್ನು ಕೊಡುತ್ತದೆ. ಅ-ಚ್ಯುತ ಅಂದರೆ ಯಾವ\nಗುಣದಿಂದಲೂ ಚ್ಯುತನಾದವನಲ್ಲ ಎಂದರ್ಥ. ಅವನಿಂದ ಚ್ಯುತನಾಗಿ ಈ ಜಗತ್ತಿಗೆ ಅಸ್ತಿತ್ವವಿಲ್ಲ. ಆತ ಸರ್ವ\nಜಗತ್ತಿಗೆ ಆಧಾರ. ಇನ್ನು ಎರಡನೇ ನಾಮ -ಅನಂತ. ಅಂತವಿಲ್ಲದ್ದು ಅನಂತ. ಯಾರ ಗುಣಗಳಿಗೆ ಕೊನೆ\nಇಲ್ಲವೋ ಅವನು ಅನಂತ. ಮೂರನೆಯ ನಾಮ ಗೋವಿಂದ. ಗೋ-ಅಂದರೆ ವೇದಗಳು. ಸಮಸ್ತ ವೇದಗಳಿಂದ\nಪ್ರತಿಪಾದ್ಯನಾದ ಭಗವಂತ-ಗೋವಿಂದ. ಒಟ್ಟಿನಲ್ಲಿ ಸಂಕ್ಷಿಪ್ತವಾಗಿ ಇಲ್ಲಿ - ಓಂ ತತ್‌ ಸತ್‌ ಎಂದರೆ\n“ಜಗದಾಧಾರನೂ, ಸಮಸ್ತ ಗುಣಪೂರ್ಣನೂ, ಸಮಸ್ತ ವೇದ ಪ್ರತಿಪಾದ್ಯನೂ, ಸಮಸ್ತ ದೋಷ ದೂರನೂ ಆದ\n\nಭಗವಂತ” ಎಂದರ್ಥ. ಇಂತಹ ಭಗವಂತ ವೇದವನ್ನು ಸೃಷ್ಟಿ ಮಾಡಿದ, ಅದರಿಂದ 'ಜ್ಞಾನಿಗಳಾಗಿ' ಎಂದು\nವೇದಜ್ಞ(ಜ್ಞಾನಿ)ರನ್ನು ಸೃಷ್ಟಿ ಮಾಡಿದ, ಜ್ಞಾನ ಪೂರ್ವಕವಾಗಿ ಕರ್ಮ ಮಾಡಿರೆಂದು ಯಜ್ಞವನ್ನು ಸೃಷ್ಟಿ ಮಾಡಿದ.\n\nನಮ್ಮಲ್ಲಿ ಕೆಲವರು ವೇದ-'ಪೌರುಷೇಯ' ಎಂದೂ, ಹಾಗೂ ಇನ್ನು ಕೆಲವರು ವೇದ-\"ಅಪೌರುಷೇಯ' ಎಂದೂ\nವಾದ ಮಾಡುವವರಿದ್ದಾರೆ. ಸೃಷ್ಟಿ ಪೂರ್ವದಲ್ಲಿ ಪರಮಪುರುಷನಿಂದ ಉಚ್ಚರಿಸಲ್ಪಟ್ಟ ವೇದ ಪೌರುಷೇಯ; ಇದು\nಅನಾದಿ-ಅನಂತ ಕಾಲದಲ್ಲಿ ಪ್ರತೀ ಕಲ್ಪದಲ್ಲೂ ಭಗವಂತನಿಂದ ಉಚ್ಚರಿಸಲ್ಪಡುವುದರಿಂದ ಅಪೌರುಷೇಯ\nಕೂಡಾ ಹೌದು. ಆದ್ದರಿಂದ ಈ ಕುರಿತು ಮಾಡುವ ವಾದ ವ್ಯರ್ಥ.\n",
  "17.24": "ತಸ್ಮಾತ್‌ ಓಂ ಇತಿ ಉದಾಹೃತ್ಯ ಯಜ್ಞ ದಾನ ತಪಃ ಕ್ರಿಯಾಃ |\n\nಪ್ರವರ್ತಂತೇ ವಿಧಾನ ಉಕ್ತಾಃ ಸತತಮ್‌ ಬ್ರಹ್ಮವಾದಿನಾಮ್‌ ಎ ಆದ್ದರಿಂದ ಶಾಸ್ತ್ರದ ಕಟ್ಟಳೆಗೆ ಅನುಗುಣವಾದ,\nಬ್ರಹ್ಮ ಚಿಂತಕರ ಯಜ್ಞ, ದಾನ ಮತ್ತು ತಪದ ಕ್ರಿಯೆಗಳು ಯಾವಾಗಲೂ 'ಓಂ' ಎಂದು ಭಗವಂತನ ನಾಮ\nಸ್ಮರಣೆಯ ಜತೆಗೆಯೇ ತೊಡಗುತ್ತವೆ.\n\nಕರ್ಮದಲ್ಲಿ ಓಂಕಾರ ಬಳಕೆಯ ಮಹತ್ವವನ್ನು ಕೃಷ್ಣ ಇಲ್ಲಿ ವಿವರಿಸಿದ್ದಾನೆ. ನಮಗೆ ತಿಳಿದಂತೆ ಒಬ್ಬ\nವೇದಜ್ಜನಾಗಬೇಕಾದರೆ ಆತನಿಗೆ ಓಂಕಾರದ ಉಪದೇಶವಾಗಿರಬೇಕು; ಯಜ್ಞದ ಆದಿ-ಅಂತದಲ್ಲಿ ಓಂಕಾರ\nಹೇಳಬೇಕು; ವೇದ ಪಠಣದ ಆದಿ-ಅಂತದಲ್ಲಿ ಓಂಕಾರವಿರಬೇಕು. ಇದೆಲ್ಲವೂ ಹಿಂದಿನಿಂದಲೂ ಬಂದಿರುವ\nಆಚರಣೆಗಳು. ನಾವು ಮಾಡುವ ಯಾವ ಕಾರ್ಯವೇ ಇರಲಿ, ಅದನ್ನು ಪ್ರಾರಂಭಿಸುವಾಗ “ಇದನ್ನು ಭಗವಂತನ\nಪೂಜಾರೂಪವಾಗಿ ಮಾಡುತ್ತೇನೆ” ಎನ್ನುವ ಸಂಕಲ್ಪ ಮಾಡಿ ಮಾಡುವುದು ಮತ್ತು ಅಂತ್ಯದಲ್ಲಿ “ನಾನು\nಮಾಡಿದ್ದನ್ನು ಭಗವಂತ ಸ್ವೀಕರಿಸಲಿ” ಎಂದು ಹೇಳುವುದು-ಇದರ ಮೂಲ ಉದ್ದೇಶ. ಹೀಗೆ ಓಂಕಾರ ಹೇಳಿಯೇ\nಕರ್ಮ ಮಾಡಬೇಕು ಎನ್ನುವ ಆಚರಣೆ ಹಿಂದಿನಿಂದ ಬೆಳೆದುಬಂತು. ಈ ಅನುಸಂಧಾನದಿಂದ ನಾವು ಯಾವುದೇ\nಪಾರಾಯಣ, ಹೋಮ, ಹವನ, ಯಜ್ಞ, ತಪಸ್ಸು, ದಾನ ಮಾಡಿದರೂ ಕೂಡಾ ಅದು ಸಾತ್ವಿಕ ಕರ್ಮವೆನಿಸುತ್ತದೆ.\n\nತತ್‌ ಇತಿ ಅನಭಿಸಂಧಾಯ ಫಲಂ ಯಜ್ಞ ತಪಃ ಕ್ರಿಯಾಃ |\nದಾನ ಕ್ರಿಯಾಃ ಚ ವಿವಿಧಾಃ ಕ್ರಿಯಂತೇ ಮೋಕ್ಷಕಾಂಕ್ಷಿಭಿಃ - ಮೋಕ್ಷ ಬಯಸುವ ಸಜ್ಜನರು ಫಲವನ್ನು ಬಯಸದೆ,\n“ತತ್‌' ಎನಿಸಿದ ಭಗವಂತನಿಗಾಗಿ ಬಗೆಬಗೆಯ ಯಜ್ಞ, ದಾನ ಮತ್ತು ತಪದ ಕ್ರಿಯೆಗಳನ್ನು ಆಚರಿಸುತ್ತಾರೆ.\n\n'ತತ್‌' ಎನ್ನುವುದು ಸಮಸ್ತ ವೇದ ವಾಚ್ಯನಾದ ಭಗವಂತನನ್ನು ಹೇಳುತ್ತದೆ ಎನ್ನುವುದನ್ನು ಹಿಂದೆ ನೋಡಿದ್ದೇವೆ.\nಇಲ್ಲಿ-ನಾವು ಮಾಡುವ ಕರ್ಮದಲ್ಲಿ “ತತ್‌' ಏನನ್ನು ಹೇಳುತ್ತದೆ ಎನ್ನುವುದನ್ನು ಕೃಷ್ಣ ವಿವರಿಸಿದ್ದಾನೆ. ತತ್‌'\nಎನ್ನುವುದು ವೇದಮಾತಾ ಗಾಯತ್ರಿಯ ಸಂಕ್ಷಿಪ್ತಪದ(Abbreviation; ಮೊದಲ ಮತ್ತು ಕೊನೆಯ ಅಕ್ಷರ)\nಹೀಗಾಗಿ ಇದು ಗಾಯತ್ರಿ ವಾಚ್ಯ ಭಗವಂತನ ಮುಖ್ಯ ನಾಮಧೇಯ. 'ತತ್‌' ಎನ್ನುವುದು ಕರ್ಮದಲ್ಲಿ\nಭಗವಂತನು ಕೊಡುವ ಫಲವನ್ನು ಹೇಳುತ್ತದೆ. 'ತತ್‌' ಎಂದರೆ ಯಾವುದೇ ಐಹಿಕ ಫಲದ ಆಸೆ ಇಲ್ಲದೆ,\nಭವಬಂಧನದಿಂದ ಬಿಡುಗಡೆಗೊಳಿಸಿ ಮೋಕ್ಷವನ್ನು ಕೊಡುವ ಭಗವಂತನ ಪ್ರೀತಿಗಾಗಿ ಮಾಡುವ ಕರ್ಮ. ಅದು\nಯಜ್ಞವಿರಬಹುದು, ತಪಸ್ಸಿರಬಹುದು ಅಥವಾ ದಾನವಿರಬಹುದು. ಜ್ಞಾನಿಗಳು ದಾನ ಮಾಡುವಾಗ ಕೂಡಾ\nಯಾವುದೇ ಐಹಿಕ ಫಲದ ಅಪೇಕ್ಷೆ ಇಲ್ಲದೆ ದಾನ ಮಾಡುತ್ತಾರೆ. ಉದಾಹರಣೆಗೆ ಅನ್ನದಾನ: ಅನ್ನದ ಅಭಿಮಾನಿ\nಲಕ್ಷ್ಮಿ; ಅನ್ನದಾನ ಎಂದರೆ ದಾನ ಸ್ವೀಕರಿಸುವವನೊಳಗಿರುವ ವೈಶ್ವಾನರ ರೂಪಿ ನಾರಾಯಣನಿಗೆ ಲಕ್ಷ್ಮಿಯ\nಸಮರ್ಪಣೆ. ಇದೇ ರೀತಿ ಕನ್ಯಾದಾನ: ಕನ್ಯಾದಾನ ಮಾಡುವಾಗ ಕನ್ಯಾಪಿತೃಗಳು ಗಂಡಿನ ಆಸ್ತಿ, ಹುದ್ದೆ,\nಸಂಬಳ ನೋಡಿ ದಾನ ಮಾಡುವುದಲ್ಲ. ಬದಲಿಗೆ ಹುಡುಗಿಯ ಒಳಗಿರುವ ಲಕ್ಷ್ಮಿಯನ್ನು ಹುಡುಗನ ಒಳಗಿರುವ\nನಾರಾಯಣನಿಗೆ ಅರ್ಪಿತವಾಗಲಿ ಎನ್ನುವ ಅನುಸಂಧಾನದಿಂದ ನೀಡುವುದು. ಹೀಗೆ ಮೋಕ್ಷಕಾಂಕ್ಷಿಗಳು\n“ಎಲ್ಲಾ ಮಾಡಿಸುವವನು ಆ ಭಗವಂತ-ಅವನ ಪ್ರೀತ್ಯರ್ಥ ಈ ಪೂಜೆ” ಎಂದು ಯಾವುದೇ ಲೌಕಿಕ ಫಲಾಪೇಕ್ಷೆ\nಇಲ್ಲದೆ ಕ್ರಿಯೆವನ್ನು ಮಾಡುತ್ತಾರೆ. ಇದು “ತತ್‌',\n",
  "17.25": "ತಸ್ಮಾತ್‌ ಓಂ ಇತಿ ಉದಾಹೃತ್ಯ ಯಜ್ಞ ದಾನ ತಪಃ ಕ್ರಿಯಾಃ |\n\nಪ್ರವರ್ತಂತೇ ವಿಧಾನ ಉಕ್ತಾಃ ಸತತಮ್‌ ಬ್ರಹ್ಮವಾದಿನಾಮ್‌ ಎ ಆದ್ದರಿಂದ ಶಾಸ್ತ್ರದ ಕಟ್ಟಳೆಗೆ ಅನುಗುಣವಾದ,\nಬ್ರಹ್ಮ ಚಿಂತಕರ ಯಜ್ಞ, ದಾನ ಮತ್ತು ತಪದ ಕ್ರಿಯೆಗಳು ಯಾವಾಗಲೂ 'ಓಂ' ಎಂದು ಭಗವಂತನ ನಾಮ\nಸ್ಮರಣೆಯ ಜತೆಗೆಯೇ ತೊಡಗುತ್ತವೆ.\n\nಕರ್ಮದಲ್ಲಿ ಓಂಕಾರ ಬಳಕೆಯ ಮಹತ್ವವನ್ನು ಕೃಷ್ಣ ಇಲ್ಲಿ ವಿವರಿಸಿದ್ದಾನೆ. ನಮಗೆ ತಿಳಿದಂತೆ ಒಬ್ಬ\nವೇದಜ್ಜನಾಗಬೇಕಾದರೆ ಆತನಿಗೆ ಓಂಕಾರದ ಉಪದೇಶವಾಗಿರಬೇಕು; ಯಜ್ಞದ ಆದಿ-ಅಂತದಲ್ಲಿ ಓಂಕಾರ\nಹೇಳಬೇಕು; ವೇದ ಪಠಣದ ಆದಿ-ಅಂತದಲ್ಲಿ ಓಂಕಾರವಿರಬೇಕು. ಇದೆಲ್ಲವೂ ಹಿಂದಿನಿಂದಲೂ ಬಂದಿರುವ\nಆಚರಣೆಗಳು. ನಾವು ಮಾಡುವ ಯಾವ ಕಾರ್ಯವೇ ಇರಲಿ, ಅದನ್ನು ಪ್ರಾರಂಭಿಸುವಾಗ “ಇದನ್ನು ಭಗವಂತನ\nಪೂಜಾರೂಪವಾಗಿ ಮಾಡುತ್ತೇನೆ” ಎನ್ನುವ ಸಂಕಲ್ಪ ಮಾಡಿ ಮಾಡುವುದು ಮತ್ತು ಅಂತ್ಯದಲ್ಲಿ “ನಾನು\nಮಾಡಿದ್ದನ್ನು ಭಗವಂತ ಸ್ವೀಕರಿಸಲಿ” ಎಂದು ಹೇಳುವುದು-ಇದರ ಮೂಲ ಉದ್ದೇಶ. ಹೀಗೆ ಓಂಕಾರ ಹೇಳಿಯೇ\nಕರ್ಮ ಮಾಡಬೇಕು ಎನ್ನುವ ಆಚರಣೆ ಹಿಂದಿನಿಂದ ಬೆಳೆದುಬಂತು. ಈ ಅನುಸಂಧಾನದಿಂದ ನಾವು ಯಾವುದೇ\nಪಾರಾಯಣ, ಹೋಮ, ಹವನ, ಯಜ್ಞ, ತಪಸ್ಸು, ದಾನ ಮಾಡಿದರೂ ಕೂಡಾ ಅದು ಸಾತ್ವಿಕ ಕರ್ಮವೆನಿಸುತ್ತದೆ.\n\nತತ್‌ ಇತಿ ಅನಭಿಸಂಧಾಯ ಫಲಂ ಯಜ್ಞ ತಪಃ ಕ್ರಿಯಾಃ |\nದಾನ ಕ್ರಿಯಾಃ ಚ ವಿವಿಧಾಃ ಕ್ರಿಯಂತೇ ಮೋಕ್ಷಕಾಂಕ್ಷಿಭಿಃ - ಮೋಕ್ಷ ಬಯಸುವ ಸಜ್ಜನರು ಫಲವನ್ನು ಬಯಸದೆ,\n“ತತ್‌' ಎನಿಸಿದ ಭಗವಂತನಿಗಾಗಿ ಬಗೆಬಗೆಯ ಯಜ್ಞ, ದಾನ ಮತ್ತು ತಪದ ಕ್ರಿಯೆಗಳನ್ನು ಆಚರಿಸುತ್ತಾರೆ.\n\n'ತತ್‌' ಎನ್ನುವುದು ಸಮಸ್ತ ವೇದ ವಾಚ್ಯನಾದ ಭಗವಂತನನ್ನು ಹೇಳುತ್ತದೆ ಎನ್ನುವುದನ್ನು ಹಿಂದೆ ನೋಡಿದ್ದೇವೆ.\nಇಲ್ಲಿ-ನಾವು ಮಾಡುವ ಕರ್ಮದಲ್ಲಿ “ತತ್‌' ಏನನ್ನು ಹೇಳುತ್ತದೆ ಎನ್ನುವುದನ್ನು ಕೃಷ್ಣ ವಿವರಿಸಿದ್ದಾನೆ. ತತ್‌'\nಎನ್ನುವುದು ವೇದಮಾತಾ ಗಾಯತ್ರಿಯ ಸಂಕ್ಷಿಪ್ತಪದ(Abbreviation; ಮೊದಲ ಮತ್ತು ಕೊನೆಯ ಅಕ್ಷರ)\nಹೀಗಾಗಿ ಇದು ಗಾಯತ್ರಿ ವಾಚ್ಯ ಭಗವಂತನ ಮುಖ್ಯ ನಾಮಧೇಯ. 'ತತ್‌' ಎನ್ನುವುದು ಕರ್ಮದಲ್ಲಿ\nಭಗವಂತನು ಕೊಡುವ ಫಲವನ್ನು ಹೇಳುತ್ತದೆ. 'ತತ್‌' ಎಂದರೆ ಯಾವುದೇ ಐಹಿಕ ಫಲದ ಆಸೆ ಇಲ್ಲದೆ,\nಭವಬಂಧನದಿಂದ ಬಿಡುಗಡೆಗೊಳಿಸಿ ಮೋಕ್ಷವನ್ನು ಕೊಡುವ ಭಗವಂತನ ಪ್ರೀತಿಗಾಗಿ ಮಾಡುವ ಕರ್ಮ. ಅದು\nಯಜ್ಞವಿರಬಹುದು, ತಪಸ್ಸಿರಬಹುದು ಅಥವಾ ದಾನವಿರಬಹುದು. ಜ್ಞಾನಿಗಳು ದಾನ ಮಾಡುವಾಗ ಕೂಡಾ\nಯಾವುದೇ ಐಹಿಕ ಫಲದ ಅಪೇಕ್ಷೆ ಇಲ್ಲದೆ ದಾನ ಮಾಡುತ್ತಾರೆ. ಉದಾಹರಣೆಗೆ ಅನ್ನದಾನ: ಅನ್ನದ ಅಭಿಮಾನಿ\nಲಕ್ಷ್ಮಿ; ಅನ್ನದಾನ ಎಂದರೆ ದಾನ ಸ್ವೀಕರಿಸುವವನೊಳಗಿರುವ ವೈಶ್ವಾನರ ರೂಪಿ ನಾರಾಯಣನಿಗೆ ಲಕ್ಷ್ಮಿಯ\nಸಮರ್ಪಣೆ. ಇದೇ ರೀತಿ ಕನ್ಯಾದಾನ: ಕನ್ಯಾದಾನ ಮಾಡುವಾಗ ಕನ್ಯಾಪಿತೃಗಳು ಗಂಡಿನ ಆಸ್ತಿ, ಹುದ್ದೆ,\nಸಂಬಳ ನೋಡಿ ದಾನ ಮಾಡುವುದಲ್ಲ. ಬದಲಿಗೆ ಹುಡುಗಿಯ ಒಳಗಿರುವ ಲಕ್ಷ್ಮಿಯನ್ನು ಹುಡುಗನ ಒಳಗಿರುವ\nನಾರಾಯಣನಿಗೆ ಅರ್ಪಿತವಾಗಲಿ ಎನ್ನುವ ಅನುಸಂಧಾನದಿಂದ ನೀಡುವುದು. ಹೀಗೆ ಮೋಕ್ಷಕಾಂಕ್ಷಿಗಳು\n“ಎಲ್ಲಾ ಮಾಡಿಸುವವನು ಆ ಭಗವಂತ-ಅವನ ಪ್ರೀತ್ಯರ್ಥ ಈ ಪೂಜೆ” ಎಂದು ಯಾವುದೇ ಲೌಕಿಕ ಫಲಾಪೇಕ್ಷೆ\nಇಲ್ಲದೆ ಕ್ರಿಯೆವನ್ನು ಮಾಡುತ್ತಾರೆ. ಇದು “ತತ್‌',\n",
  "17.26": "ಸತ್‌ ಭಾವೇ ಸಾಧುಭಾವೇ ಚ ಸತ್‌ ಇತಿ ಏತತ್‌ ಪ್ರಯುಜ್ಯತೇ |\nಪ್ರಶಸ್ತೇ ಕರ್ಮಣಿ ತಥಾ ಸತ್‌ ಶಬ್ದಃ ಪಾರ್ಥ ಯುಜ್ಯತೇ - ಪಾರ್ಥಾ, \"ಹುಟ್ಟು' ಮತ್ತು “ಒಳ್ಳೆಯತನ' ಎಂಬ\nಅರ್ಥದಲ್ಲಿ “ಸತ್‌' ಎಂಬ ಶಬ್ದ ಬಳಕೆಯಾಗುತ್ತದೆ. ಒಳ್ಳೆಯ ಕೆಲಸ' ಎಂಬ ಅರ್ಥದಲ್ಲೂ “ಸತ್‌' ಶಬ್ದ ಸಲ್ಲುತ್ತದೆ.\n\n'ಸತ್‌' ಅನ್ನುವುದಕ್ಕೆ ಒಂದು ಅರ್ಥ-ಭಾವ. ಸತ್‌-ಭಾವ ಎಂದರೆ ಸಜ್ಜನಿಕೆಯಿಂದ ಇರುವುದು. ಇದು ಲೋಕದಲ್ಲಿ\nವ್ಯಕ್ತಿಗೆ ಬಳಸುವ ಪದಪ್ರಯೋಗ. ಇದನ್ನು ಕರ್ಮದಲ್ಲಿ ಬಳಸಿದಾಗ ಸತ್‌-ಕರ್ಮವಾಗುತ್ತದೆ. ಓಂಕಾರ ವಾಚ್ಯ\nಭಗವಂತನಿಗೆ ಅರ್ಪಣಾ ಭಾವದಿಂದ, ಯಾವುದೇ ಫಲಾಪೇಕ್ಷೆ ಇಲ್ಲದೇ(ತತ್‌) ಮಾಡುವ ಕರ್ಮ 'ಸತ್‌'-ಕರ್ಮ.\nಯಾವ ಕರ್ಮವನ್ನು ಭಗವಂತನ ಕುರಿತಾಗಿ ಮಾಡುತ್ತೇವೋ, ಆ ಕರ್ಮ ಪ್ರಶಸ್ತವಾಗಿರಬೇಕು. ಅಂದರೆ\nಸ್ವಾರ್ಥಕ್ಕಾಗಿ ಮಾಡಿದರೆ ಅದನ್ನು ಜನ ಮೆಚ್ಚುವುದಿಲ್ಲ. ಬದಲಿಗೆ ತ್ಯಾಗದಿಂದ ಮಾಡುವ ಕರ್ಮ ಪ್ರಶಸ್ತ\nಕರ್ಮವೆನಿಸುತ್ತದೆ. ನಾವು ಈ ರೀತಿ ಪ್ರತಿಯೊಂದು ಶಬ್ದದ ಅರ್ಥವನ್ನು ತಿಳಿದು, ಪಾಲನೆ ಮಾಡುವ\nಪಾರ್ಥರಾಗಬೇಕು ಎನ್ನುವುದು ಕೃಷ್ಣನ ಸಂದೇಶ. “ಸತ್‌' ಪದದ ಅರ್ಥವನ್ನು ಇನ್ನೂ ವಿವರವಾಗಿ ಮುಂದಿನ\nಶ್ಲೋಕದಲ್ಲಿ ಕೃಷ್ಣ ವಿವರಿಸುತ್ತಾನೆ.\n",
  "17.27": "ಯಜ್ಞೇ ತಪಸಿ ದಾನೇ ಚ ಸ್ಥಿತಿಃ ಸತ್‌ ಇತಿ ಚ ಉಚ್ಯತೇ |\nಕರ್ಮ ಚ ಏವ ತತ್‌ ಅರ್ಥೀಯಂ ಸತ್‌ ಇತಿ ಏವ ಅಭಿಧೀಯತೇ - ಯಜ್ಞ-ದಾನ-ತಪಸ್ಸುಗಳಲ್ಲಿ ನಿಷ್ಠೆಯನ್ನೂ\n\"ಸತ್‌' ಎನ್ನುತ್ತಾರೆ. ಭಗವಂತನಿಗಾಗಿ ಆಚರಿಸುವ ಕರ್ಮವನ್ನೂ “ಸತ್‌' ಎಂದೇ ಕರೆಯುತ್ತಾರೆ.\n\n\"ಸತ್‌' ಎಂದರೆ “ಸತ್‌' ಶಬ್ದ ವಾಚ್ಯನಾದ ಭಗವಂತನನ್ನು ಯಜ್ಞ, ದಾನ, ತಪಸ್ಸಿನಿಂದ ಆರಾಧಿಸುವುದು. ಹೀಗಾಗಿ\nಭಗವಂತನೂ “ಸತ್‌; ಅವನ ಕುರಿತಾದ ಕರ್ಮವೂ 'ಸತ್‌'(ಸತ್ಕರ್ಮ); ಅವನ ಕುರಿತಾಗಿ ಕರ್ಮ\nಮಾಡುವವನೂ 'ಸತ್‌'(ಸಜ್ಜನ). ನಾವು ಭಗವಂತನ ಎಚ್ಚರದಿಂದ, ಫಲಾಪೇಕ್ಷೆ ಇಲ್ಲದೆ, ಭಗವದರ್ಪಣಾ\nಭಾವದಿಂದ, ಭಗವಂತ ಪ್ರೀತನಾಗಲಿ ಎಂದು ಮಾಡುವ ಸಮಸ್ತ ಕರ್ಮವೂ ಸತ್‌-ಕರ್ಮ.\n",
  "17.28": "ಅಶ್ರದ್ಧಯಾ ಹುತಮ್‌ ದತ್ತಮ್‌ ತಪಃ ತಪ್ತಮ್‌ ಕೃತಂ ಚಯತ್‌ |\n\nಅಸತ್‌ ಇತಿ ಉಚ್ಯತೇ ಪಾರ್ಥ ನ ಚ ತತ್‌ ಪ್ರೇತ್ಯ ನೋ ಇಹ - ಮಾಡುವ ಕರ್ಮದಲ್ಲಿ ಶ್ರದ್ಧೆ ಇಲ್ಲದೆ,\nಭಗವಂತನಲ್ಲಿ ಶ್ರದ್ಧೆ ಇಲ್ಲದೆ, ಯಾರದ್ದೋ ಒತ್ತಾಯಕ್ಕಾಗಿ, ಅಥವಾ ಭಯದಿಂದ, ಪೂರ್ಣ ನಂಬಿಕೆ ಇಲ್ಲದೆ\nಮಾಡುವ ಕ್ರಿಯೆ ವ್ಯರ್ಥ. ಶ್ರದ್ದೆ ಇಲ್ಲದೆ ಮಾಡುವ ಇಂತಹ ದಾನ, ತಪಸ್ಸು, ಯಜ್ಞ, ಅಥವಾ ಇತರ ಯಾವುದೇ\n\nಕರ್ಮಕ್ಕೆ ಇಹದಲ್ಲೂ ಫಲವಿಲ್ಲ, ಪರದಲ್ಲೂ ಫಲವಿಲ್ಲ.\n\nಇತಿ ಸಪ್ತದಶೋ$ಧ್ಯಾಯಃ\nಹದಿನೇಳನೆಯ ಅಧ್ಯಾಯ ಮುಗಿಯಿತು\n\nಅಧ್ಯಾಯ ಹದಿನೆಂಟು\n\nಹಿಂದಿನ ಹದಿನೇಳು ಅಧ್ಯಾಯಗಳಲ್ಲಿ ನಮ್ಮ ಸಾಧನೆ ಹೇಗಿರಬೇಕು ಎನ್ನುವುದನ್ನು ವಿವರಿಸಿದ್ದ ಕೃಷ್ಣ, ಇಲ್ಲಿ ಆ\nಸಾಧನೆಯ ಸಂದೇಶವನ್ನು ಸಂಗ್ರಹ ರೂಪದಲ್ಲಿ ನಮ್ಮ ಮುಂದಿಟ್ಟಿದ್ದಾನೆ. ಇದರ ಜೊತೆಗೆ ಅಧ್ಯಾಯ\nಹದಿನೇಳರಲ್ಲಿ ವಿವರಿಸದೇ ಇರುವ ಸಾಧನೆಗೆ ಕುರಿತಾದ ತ್ರೈಗುಣ್ಯದ ಮುಂದುವರಿದ ವಿವರಣೆ ಕೂಡಾ ಇಲ್ಲಿದೆ.\nಇದು ಗೀತೆಯ ಉಪಸಂಹಾರ. ಈ ಅಧ್ಯಾಯ ಅರ್ಜುನನ ಪ್ರಶ್ನೆ ಯೊಂದಿಗೆ ಆರಂಭವಾಗುತ್ತದೆ.\n\nಅರ್ಜುನ ಉವಾಚ |\nಸಂನ್ಯಾಸಸ್ಯ ಮಹಾಬಾಹೋ ತತ್ವಮಿಚ್ಛಾಮಿ ವೇದಿತುಮ್‌ |\nತ್ಯಾಗಸ್ಯ ಚ ಹೃಷೀಕೇಶ ಪೃಥಕ್‌ ಕೇಶಿನಿಸೂದನ ॥೧॥\n\nಅರ್ಜುನಃ ಉವಾಚ-ಅರ್ಜುನ ಕೇಳಿದನು:\n\nಸಂನ್ಯಾಸಸ್ಯ ಮಹಾಬಾಹೋ ತತ್ವಮ್‌ ಇಚ್ಛಾಮಿ ವೇದಿತುಮ್‌ ।\n\nತ್ಯಾಗಸ್ಯ ಚ ಹೃಷೀಕೇಶ ಪೃಥಕ್‌ ಕೇಶಿನಿಸೂದನ - ಮಹಾಬಾಹೋ, ಸಂನ್ಯಾಸದ ಮತ್ತು ತ್ಯಾಗದ\nಅಂತರವೇನು? ಓ ಹೃಷೀಕೇಶ, ಇದರ ನಿಜವನ್ನು ಕೇಶಿನಿಸೂದನನಾದ ನೀನು ನನಗೆ ತಿಳಿಸು.\n\nಕೃಷ್ಣ ಮೊದಲು ಸಂನ್ಯಾಸದ ಬಗ್ಗೆ ಹೇಳಿದ್ದ; ಆನಂತರ ಹಿಂದಿನ ಅಧ್ಯಾಯದಲ್ಲಿ ಯಜ್ಞ, ದಾನ, ತಪಸ್ಸು ಎನ್ನುವ\nಕರ್ಮಗಳನ್ನು ಹೇಳಿದ. ಇಲ್ಲಿ ನಮಗೆ ಸ್ವಲ್ಪ ಗೊಂದಲವಾಗುತ್ತದೆ. ಹಾಗಾಗಿ ಅರ್ಜುನ ಕೃಷ್ಣನಲ್ಲಿ ಕರ್ಮತ್ಯಾಗ\nಮತ್ತು ಕರ್ಮಸಂನ್ಯಾಸ ಇವೆರಡರ ನಡುವಿನ ಅಂತರವೇನು ಎಂದು ಕೇಳುತ್ತಾನೆ. ತ್ಯಾಗ ಮತ್ತು ಸಂನ್ಯಾಸ\nಎರಡು ಪದಗಳು ಮೇಲ್ನೋಟಕ್ಕೆ ಒಂದೇ ಅರ್ಥವನ್ನು ಕೊಟ್ಟಂತೆ ಕಂಡರೂ ಕೂಡಾ, ಅದು ಬೇರೆಬೇರೆ.\nಸಂನ್ಯಾಸ ಮತ್ತು ತ್ಯಾಗದ ಮೂಲಭೂತ ಅರ್ಥವೇನು 9 ಅವೆರಡನ್ನು ಪ್ರತ್ಯೇಕವಾಗಿ ಅರ್ಥೈಸುವುದು ಹೇಗೆ\nಎನ್ನುವುದು ಅರ್ಜುನನ ಪ್ರಶ್ನೆ.\n\nಇಲ್ಲಿ ಅರ್ಜುನ ಕೃಷ್ಣನನ್ನು ಮಹಾಬಾಹೋ, ಹೃಷೀಕೇಶ ಮತ್ತು ಕೇಶಿನಿಸೂದನ ಎನ್ನುವ ಮೂರು ದಿವ್ಯ\nನಾಮಗಳಿಂದ ಸಂಬೋಧಿಸಿದ್ದಾನೆ. ಇದು ಆತನಲ್ಲಿರುವ ಗುರುಭಕ್ತಿಯನ್ನು ಸೂಚಿಸುತ್ತದೆ ಮತ್ತು ಕೃಷ್ಣ ಕೇವಲ\nವಸುದೇವನ ಮಗನಲ್ಲ, ಅವನು “ಭಗವಂತ' ಎಂದು ಅರ್ಥ ಮಾಡಿಕೊಂಡು ಈ ಪ್ರಶ್ನೆ ಕೇಳಿರುವುದು ಇಲ್ಲಿ\nಸ್ಪಷ್ಟವಾಗಿ ತಿಳಿಯುತ್ತದೆ. “ಮಹಾಬಾಹು' ಎಂದರೆ ಶತ್ರುಗಳನ್ನು ಎದುರಿಸುವ, ನೀಳವಾದ, ಗಟ್ಟಿಯಾದ\nತೊಳುಗಳುಳ್ಳವ ಎನ್ನುವುದು ಮೇಲ್ನೋಟದ ಅರ್ಥ. ದುಷ್ಟನಿಗ್ರಹ ಮಾಡಿ ಶಿಷ್ಟ ರಕ್ಷಣೆ ಮಾಡುವ, ಎಲ್ಲರೊಳಗಿನ\nಅಜ್ಞಾನವನ್ನು ನೀಗಿಸುವ, ಲೋಕರಕ್ಷಕ ತೋಳುಳ್ಳವ ಎನ್ನುವುದು ಈ ದಿವ್ಯ ನಾಮದ ಹಿಂದಿರುವ ಮೂಲ ಅರ್ಥ.\nಇನ್ನು 'ಹೃಷೀಕ' ಎಂದರೆ ಇಂದ್ರಿಯಗಳು. ಪಿಂಡಾಂಡದೊಳಗಿದ್ದು ಸರ್ವ ಇಂದ್ರಿಯಗಳನ್ನು ನಿಯಂತ್ರಿಸುವ\nಭಗವಂತ ಹೃಷೀಕೇಶ. “ಕೇಶಿ' ಅಂದರೆ ಸೂರ್ಯಕಿರಣ; ವಾಯುದೇವರು.\n\nಸೌರಮಂಡಲದಲ್ಲಿದ್ದು; ತನ್ನ ಅಂತರಂಗದ ಭಕ್ತನಾದ ಪ್ರಾಣದೇವರಲ್ಲಿದ್ದು; ನಮ್ಮ ಅಭೀಷ್ಟವನ್ನು ಪೂರೈಸುವ,\n\nನಮಗೆ ಶಕ್ತಿತುಂಬುವ ಭಗವಂತ *ಕೇಶಿನಿಸೂದನ'. ಅವನು ಬ್ರಹ್ಮಾಂಡ ಮತ್ತು ಪಿಂಡಾಂಡದೊಳಗಿದ್ದು ಇಡೀ\nವಿಶ್ವವನ್ನು ನಿಯಂತ್ರಿಸುವ ಮಹಾಶಕ್ತಿ . (ಹೆಚ್ಚಿನ ಕಡೆ “ಕೇಶಿನಿಷೂದನ' ಎನ್ನುವ ಪದ ಬಳಕೆಯಲ್ಲಿದೆ, ಆದರೆ\nಸರಿಯಾದ ಪದ ಕೇಶಿನಿಸೂದನ).\nಭಗವಾನುವಾಚ ।\nಕಾಮ್ಯಾನಾಂ ಕರ್ಮಣಾಂ ನ್ಯಾಸಂ ಸಂನ್ಯಾಸಂ ಕವಯೋ ವಿದುಃ ।\n\nಭ್ರ ಭ್ರ\nಸರ್ವಕರ್ಮಫಲತ್ಯಾಗಂ ಪ್ರಾಹುಸ್ವಾಗಂ ವಿಚಕ್ಷಣಾಃ ॥೨॥\n\nಭಗವಾನ್‌ ಉವಾಚ- ಭಗವಂತ ಹೇಳಿದನು:\nಕಾಮ್ಯಾನಾಮ್‌ ಕರ್ಮಣಾಮ್‌ ನ್ಯಾಸಮ್‌ ಸಂನ್ಯಾಸಂ ಕವಯಃ ವಿದುಃ |\nಸರ್ವಕರ್ಮಫಲ ತ್ಯಾಗಮ್‌ ಪ್ರಾಹುಃ ತ್ಯಾಗಂ ವಿಚಕ್ಷಣಾಃ -ಕಾಮ್ಯ ಕರ್ಮಗಳನ್ನು ತೊರೆಯುವುದನ್ನು ಬಲ್ಲವರು\n'ಸಂನ್ಯಾಸ' ಎನ್ನುತ್ತಾರೆ. ಎಲ್ಲಾ ಕರ್ಮಗಳ ಫಲವನ್ನಷ್ಟೇ ತೊರೆಯುವುದನ್ನು ತಿಳಿದವರು \"ತ್ಯಾಗ' ಎನ್ನುತ್ತಾರೆ.\nಇಲ್ಲಿ ಹೇಳುವ ಸಂನ್ಯಾಸ ಗೃಹಸ್ಥರನ್ನೂ ಒಳಗೊಂಡು ಎಲ್ಲಾ ಸಾಧಕರಿಗೂ ಅನ್ವಯವಾಗುವ ಸಂನ್ಯಾಸ.\nಸಂನ್ಯಾಸದಲ್ಲಿ ಎರಡು ವಿಧ. ಒಂದು ಕರ್ಮದ ಫಲವನ್ನು ಬಿಡುವುದು, ಇನ್ನೊಂದು ಬಯಕೆಗಳಿಂದ ಪ್ರೇರಿತವಾದ\nಕರ್ಮವನ್ನೇ ತ್ಯಾಗ ಮಾಡುವುದು. ಇಲ್ಲಿ ತ್ಯಾಗ ಎಂದರೆ ಕರ್ಮವನ್ನು ತ್ಯಾಗ ಮಾಡುವುದಲ್ಲ, ಬದಲಿಗೆ ಯಾವ\nಕರ್ಮವೇ ಇರಲಿ, ಅದನ್ನು ಮಾಡಿ-ಯಾವುದೇ ಫಲವನ್ನು ಬಯಸದೇ ಇರುವುದು. ಆದ್ದರಿಂದ ಕರ್ಮತ್ಯಾಗ\nಎಂದರೆ: ವೇದಾಧ್ಯಯನ ಬಿಡುವುದು, ಸಂಧ್ಯಾವಂದನೆ ಬಿಡುವುದು, ವೃತಾನುಷ್ಠಾನ ಇತ್ಯಾದಿಯನ್ನು ಬಿಡುವುದು\nಎಂದಲ್ಲ. ಬದಲಿಗೆ ಸತ್ಕರ್ಮವನ್ನು ಮಾಡಿ ಅದರ ಫಲವನ್ನು ಬಯಸದೇ ಇರುವುದು ಎಂದರ್ಥ. ಯಾವ\nಕರ್ಮವೇ ಇರಲಿ ಅದನ್ನು ಭಗವದ್‌ ಪ್ರೀತ್ಯರ್ತ ಮಾಡು-ಫಲ ಬಯಕೆಯಿಂದಲ್ಲ.\nಇಲ್ಲಿ ಕವಯಃ ಮತ್ತು ವಿಚಕ್ಷಣಾಃ ಎನ್ನುವ ಎರಡು ವಿಶೇಷ ಪದಗಳನ್ನು ಬಳಸಲಾಗಿದೆ. ಶಬ್ದಾರ್ಥದ\nಸಂಬಂಧವನ್ನು ತಿಳಿದವರು-ಕವಿಗಳು; ಶಬ್ದಾರ್ಥವನ್ನು ತಿಳಿದು ಅದನ್ನು ಅನುಭವಿಸಿ ಆಚರಿಸುವವರು\nವಿಚಕ್ಷಣರು. “ಕವಿಗಳು ಮತ್ತು ವಿಚಕ್ಷಣರು ಸಂನ್ಯಾಸ ಮತ್ತು ತ್ಯಾಗಕ್ಕೆ ಈ ವಿವರಣೆಯನ್ನು ಕೊಡುತ್ತಾರೆ”\nಎಂದಿದ್ದಾನೆ ಕೃಷ್ಣ.\nತ್ಯಾಜ್ಯಂ ದೋಷವದಿತ್ಯೇಕೇ ಕರ್ಮ ಪ್ರಾಹುರ್ಮನೀಷಿಣಃ |\nಯಜ್ಞದಾನತಪಃಕರ್ಮ ನ ತ್ಯಾಜ್ಯಮಿತಿ ಚಾಪರೇ ॥೩॥\n\nತ್ಯಾಜ್ಯಂ ದೋಷವತ್‌ ಇತಿ ಏಕೇ ಕರ್ಮ ಪ್ರಾಹುಃ ಮನೀಷಿಣಃ |\n\nಯಜ್ಞದಾನತಪಃಕರ್ಮ ನ ತ್ಯಾಜ್ಯಮ್‌ ಇತಿ ಚ ಅಪರೇ -",
  "18.1": "ಅಧ್ಯಾಯ ಹದಿನೆಂಟು\n\nಹಿಂದಿನ ಹದಿನೇಳು ಅಧ್ಯಾಯಗಳಲ್ಲಿ ನಮ್ಮ ಸಾಧನೆ ಹೇಗಿರಬೇಕು ಎನ್ನುವುದನ್ನು ವಿವರಿಸಿದ್ದ ಕೃಷ್ಣ, ಇಲ್ಲಿ ಆ\nಸಾಧನೆಯ ಸಂದೇಶವನ್ನು ಸಂಗ್ರಹ ರೂಪದಲ್ಲಿ ನಮ್ಮ ಮುಂದಿಟ್ಟಿದ್ದಾನೆ. ಇದರ ಜೊತೆಗೆ ಅಧ್ಯಾಯ\nಹದಿನೇಳರಲ್ಲಿ ವಿವರಿಸದೇ ಇರುವ ಸಾಧನೆಗೆ ಕುರಿತಾದ ತ್ರೈಗುಣ್ಯದ ಮುಂದುವರಿದ ವಿವರಣೆ ಕೂಡಾ ಇಲ್ಲಿದೆ.\nಇದು ಗೀತೆಯ ಉಪಸಂಹಾರ. ಈ ಅಧ್ಯಾಯ ಅರ್ಜುನನ ಪ್ರಶ್ನೆ ಯೊಂದಿಗೆ ಆರಂಭವಾಗುತ್ತದೆ.\n\nಅರ್ಜುನ ಉವಾಚ |\nಸಂನ್ಯಾಸಸ್ಯ ಮಹಾಬಾಹೋ ತತ್ವಮಿಚ್ಛಾಮಿ ವೇದಿತುಮ್‌ |\nತ್ಯಾಗಸ್ಯ ಚ ಹೃಷೀಕೇಶ ಪೃಥಕ್‌ ಕೇಶಿನಿಸೂದನ ॥೧॥\n\nಅರ್ಜುನಃ ಉವಾಚ-ಅರ್ಜುನ ಕೇಳಿದನು:\n\nಸಂನ್ಯಾಸಸ್ಯ ಮಹಾಬಾಹೋ ತತ್ವಮ್‌ ಇಚ್ಛಾಮಿ ವೇದಿತುಮ್‌ ।\n\nತ್ಯಾಗಸ್ಯ ಚ ಹೃಷೀಕೇಶ ಪೃಥಕ್‌ ಕೇಶಿನಿಸೂದನ - ಮಹಾಬಾಹೋ, ಸಂನ್ಯಾಸದ ಮತ್ತು ತ್ಯಾಗದ\nಅಂತರವೇನು? ಓ ಹೃಷೀಕೇಶ, ಇದರ ನಿಜವನ್ನು ಕೇಶಿನಿಸೂದನನಾದ ನೀನು ನನಗೆ ತಿಳಿಸು.\n\nಕೃಷ್ಣ ಮೊದಲು ಸಂನ್ಯಾಸದ ಬಗ್ಗೆ ಹೇಳಿದ್ದ; ಆನಂತರ ಹಿಂದಿನ ಅಧ್ಯಾಯದಲ್ಲಿ ಯಜ್ಞ, ದಾನ, ತಪಸ್ಸು ಎನ್ನುವ\nಕರ್ಮಗಳನ್ನು ಹೇಳಿದ. ಇಲ್ಲಿ ನಮಗೆ ಸ್ವಲ್ಪ ಗೊಂದಲವಾಗುತ್ತದೆ. ಹಾಗಾಗಿ ಅರ್ಜುನ ಕೃಷ್ಣನಲ್ಲಿ ಕರ್ಮತ್ಯಾಗ\nಮತ್ತು ಕರ್ಮಸಂನ್ಯಾಸ ಇವೆರಡರ ನಡುವಿನ ಅಂತರವೇನು ಎಂದು ಕೇಳುತ್ತಾನೆ. ತ್ಯಾಗ ಮತ್ತು ಸಂನ್ಯಾಸ\nಎರಡು ಪದಗಳು ಮೇಲ್ನೋಟಕ್ಕೆ ಒಂದೇ ಅರ್ಥವನ್ನು ಕೊಟ್ಟಂತೆ ಕಂಡರೂ ಕೂಡಾ, ಅದು ಬೇರೆಬೇರೆ.\nಸಂನ್ಯಾಸ ಮತ್ತು ತ್ಯಾಗದ ಮೂಲಭೂತ ಅರ್ಥವೇನು 9 ಅವೆರಡನ್ನು ಪ್ರತ್ಯೇಕವಾಗಿ ಅರ್ಥೈಸುವುದು ಹೇಗೆ\nಎನ್ನುವುದು ಅರ್ಜುನನ ಪ್ರಶ್ನೆ.\n\nಇಲ್ಲಿ ಅರ್ಜುನ ಕೃಷ್ಣನನ್ನು ಮಹಾಬಾಹೋ, ಹೃಷೀಕೇಶ ಮತ್ತು ಕೇಶಿನಿಸೂದನ ಎನ್ನುವ ಮೂರು ದಿವ್ಯ\nನಾಮಗಳಿಂದ ಸಂಬೋಧಿಸಿದ್ದಾನೆ. ಇದು ಆತನಲ್ಲಿರುವ ಗುರುಭಕ್ತಿಯನ್ನು ಸೂಚಿಸುತ್ತದೆ ಮತ್ತು ಕೃಷ್ಣ ಕೇವಲ\nವಸುದೇವನ ಮಗನಲ್ಲ, ಅವನು “ಭಗವಂತ' ಎಂದು ಅರ್ಥ ಮಾಡಿಕೊಂಡು ಈ ಪ್ರಶ್ನೆ ಕೇಳಿರುವುದು ಇಲ್ಲಿ\nಸ್ಪಷ್ಟವಾಗಿ ತಿಳಿಯುತ್ತದೆ. “ಮಹಾಬಾಹು' ಎಂದರೆ ಶತ್ರುಗಳನ್ನು ಎದುರಿಸುವ, ನೀಳವಾದ, ಗಟ್ಟಿಯಾದ\nತೊಳುಗಳುಳ್ಳವ ಎನ್ನುವುದು ಮೇಲ್ನೋಟದ ಅರ್ಥ. ದುಷ್ಟನಿಗ್ರಹ ಮಾಡಿ ಶಿಷ್ಟ ರಕ್ಷಣೆ ಮಾಡುವ, ಎಲ್ಲರೊಳಗಿನ\nಅಜ್ಞಾನವನ್ನು ನೀಗಿಸುವ, ಲೋಕರಕ್ಷಕ ತೋಳುಳ್ಳವ ಎನ್ನುವುದು ಈ ದಿವ್ಯ ನಾಮದ ಹಿಂದಿರುವ ಮೂಲ ಅರ್ಥ.\nಇನ್ನು 'ಹೃಷೀಕ' ಎಂದರೆ ಇಂದ್ರಿಯಗಳು. ಪಿಂಡಾಂಡದೊಳಗಿದ್ದು ಸರ್ವ ಇಂದ್ರಿಯಗಳನ್ನು ನಿಯಂತ್ರಿಸುವ\nಭಗವಂತ ಹೃಷೀಕೇಶ. “ಕೇಶಿ' ಅಂದರೆ ಸೂರ್ಯಕಿರಣ; ವಾಯುದೇವರು.\n\nಸೌರಮಂಡಲದಲ್ಲಿದ್ದು; ತನ್ನ ಅಂತರಂಗದ ಭಕ್ತನಾದ ಪ್ರಾಣದೇವರಲ್ಲಿದ್ದು; ನಮ್ಮ ಅಭೀಷ್ಟವನ್ನು ಪೂರೈಸುವ,\n\nನಮಗೆ ಶಕ್ತಿತುಂಬುವ ಭಗವಂತ “ಕೇಶಿನಿಸೂದನ”. ಅವನು ಬ್ರಹ್ಮಾಂಡ ಮತ್ತು ಪಿಂಡಾಂಡದೊಳಗಿದ್ದು ಇಡೀ\nವಿಶ್ವವನ್ನು ನಿಯಂತ್ರಿಸುವ ಮಹಾಶಕ್ತಿ . (ಹೆಚ್ಚಿನ ಕಡೆ “ಕೇಶಿನಿಷೂದನ' ಎನ್ನುವ ಪದ ಬಳಕೆಯಲ್ಲಿದೆ, ಆದರೆ\nಸರಿಯಾದ ಪದ ಕೇಶಿನಿಸೂದನ).",
  "18.2": "ಭಗವಾನ್‌ ಉವಾಚ- ಭಗವಂತ ಹೇಳಿದನು:\nಕಾಮ್ಯಾನಾಮ್‌ ಕರ್ಮಣಾಮ್‌ ನ್ಯಾಸಮ್‌ ಸಂನ್ಯಾಸಂ ಕವಯಃ ವಿದುಃ |\nಸರ್ವಕರ್ಮಫಲ ತ್ಯಾಗಮ್‌ ಪ್ರಾಹುಃ ತ್ಯಾಗಂ ವಿಚಕ್ಷಣಾಃ -ಕಾಮ್ಯ ಕರ್ಮಗಳನ್ನು ತೊರೆಯುವುದನ್ನು ಬಲ್ಲವರು\n'ಸಂನ್ಯಾಸ' ಎನ್ನುತ್ತಾರೆ. ಎಲ್ಲಾ ಕರ್ಮಗಳ ಫಲವನ್ನಷ್ಟೇ ತೊರೆಯುವುದನ್ನು ತಿಳಿದವರು \"ತ್ಯಾಗ' ಎನ್ನುತ್ತಾರೆ.\nಇಲ್ಲಿ ಹೇಳುವ ಸಂನ್ಯಾಸ ಗೃಹಸ್ಥರನ್ನೂ ಒಳಗೊಂಡು ಎಲ್ಲಾ ಸಾಧಕರಿಗೂ ಅನ್ವಯವಾಗುವ ಸಂನ್ಯಾಸ.\nಸಂನ್ಯಾಸದಲ್ಲಿ ಎರಡು ವಿಧ. ಒಂದು ಕರ್ಮದ ಫಲವನ್ನು ಬಿಡುವುದು, ಇನ್ನೊಂದು ಬಯಕೆಗಳಿಂದ ಪ್ರೇರಿತವಾದ\nಕರ್ಮವನ್ನೇ ತ್ಯಾಗ ಮಾಡುವುದು. ಇಲ್ಲಿ ತ್ಯಾಗ ಎಂದರೆ ಕರ್ಮವನ್ನು ತ್ಯಾಗ ಮಾಡುವುದಲ್ಲ, ಬದಲಿಗೆ ಯಾವ\nಕರ್ಮವೇ ಇರಲಿ, ಅದನ್ನು ಮಾಡಿ-ಯಾವುದೇ ಫಲವನ್ನು ಬಯಸದೇ ಇರುವುದು. ಆದ್ದರಿಂದ ಕರ್ಮತ್ಯಾಗ\nಎಂದರೆ: ವೇದಾಧ್ಯಯನ ಬಿಡುವುದು, ಸಂಧ್ಯಾವಂದನೆ ಬಿಡುವುದು, ವೃತಾನುಷ್ಠಾನ ಇತ್ಯಾದಿಯನ್ನು ಬಿಡುವುದು\nಎಂದಲ್ಲ. ಬದಲಿಗೆ ಸತ್ಕರ್ಮವನ್ನು ಮಾಡಿ ಅದರ ಫಲವನ್ನು ಬಯಸದೇ ಇರುವುದು ಎಂದರ್ಥ. ಯಾವ\nಕರ್ಮವೇ ಇರಲಿ ಅದನ್ನು ಭಗವದ್‌ ಪ್ರೀತ್ಯರ್ತ ಮಾಡು-ಫಲ ಬಯಕೆಯಿಂದಲ್ಲ.\nಇಲ್ಲಿ ಕವಯಃ ಮತ್ತು ವಿಚಕ್ಷಣಾಃ ಎನ್ನುವ ಎರಡು ವಿಶೇಷ ಪದಗಳನ್ನು ಬಳಸಲಾಗಿದೆ. ಶಬ್ದಾರ್ಥದ\nಸಂಬಂಧವನ್ನು ತಿಳಿದವರು-ಕವಿಗಳು; ಶಬ್ದಾರ್ಥವನ್ನು ತಿಳಿದು ಅದನ್ನು ಅನುಭವಿಸಿ ಆಚರಿಸುವವರು\nವಿಚಕ್ಷಣರು. “ಕವಿಗಳು ಮತ್ತು ವಿಚಕ್ಷಣರು ಸಂನ್ಯಾಸ ಮತ್ತು ತ್ಯಾಗಕ್ಕೆ ಈ ವಿವರಣೆಯನ್ನು ಕೊಡುತ್ತಾರೆ”\nಎಂದಿದ್ದಾನೆ ಕೃಷ್ಣ.",
  "18.3": "ತ್ಯಾಜ್ಯಂ ದೋಷವತ್‌ ಇತಿ ಏಕೇ ಕರ್ಮ ಪ್ರಾಹುಃ ಮನೀಷಿಣಃ |",
  "18.4": "ನಿಶ್ಚಯಮ್‌ ಶೃಣು ಮೇ ತತ್ರ ತ್ಯಾಗೇ ಭರತಸತ್ತಮ ।\nತ್ಯಾಗಃ ಹಿ ಪುರುಷವ್ಯಾಘ್ರ ತ್ರಿವಿಧಃ ಸಂಪ್ರಕೀರ್ತಿತಃ -- ಭರತಸತ್ತಮಾ, ಅದರಲ್ಲಿ ತ್ಯಾಗದ ಬಗ್ಗೆ ನನ್ನ ನಿರ್ಧಾರ\nಕೇಳು. ಪುರುಷವ್ಯಾಘ್ರಾ, ಮೂರು ಬಗೆಯ ತ್ಯಾಗ ಉಕ್ತವಾಗಿದೆ.\n\n“ತ್ಯಾಗದ ವಿಷಯದಲ್ಲಿ ನಿಶ್ಚಿತವಾದ ಅಭಿಪ್ರಾಯವನ್ನು ನಿನಗೆ ಹೇಳುತ್ತೇನೆ” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಹೇಗೆ ಯಜ್ಞ-\nದಾನ-ತಪಸ್ಸು ಮೂರು ವಿಧವೋ ಹಾಗೇ ತ್ಯಾಗವೂ ಕೂಡಾ ಮೂರು ವಿಧ. ಅದನ್ನು ಕೃಷ್ಣ ಅರ್ಜುನನಿಗೆ\nವಿವರಿಸುತ್ತಾನೆ. ಇಲ್ಲಿ ಕೃಷ್ಣ ಅರ್ಜುನನನ್ನು ಭರತಸತ್ತಮ ಮತ್ತು ಪುರುಷವ್ಯಾಘ್ರ ಎಂದು ಸಂಬೋಧಿಸಿದ್ದಾನೆ.\nಭರತವಂಶದ ಅರಸರ ಮಾಲಿಕೆಯಲ್ಲಿ ಗಣ್ಯನಾದ್ದರಿಂದ ಅರ್ಜುನ ಭರತಸತ್ತಮ-ಇದು ಮೇಲ್ನೋಟದ ಅರ್ಥ.\nಭಗವಂತನಲ್ಲಿ ಮತ್ತು ಜ್ಞಾನದಲ್ಲಿ ರತನಾದವ, ಭಕ್ತಿ ಉಳ್ಳವ ಭರತಸತ್ತಮ ಎನ್ನುವುದು ಈ ಸಂಬೋಧನೆಯ\nಅಂತರಂಗದ ಅರ್ಥ. ಅದೇ ರೀತಿ ಪುರುಷವ್ಯಾಘ್ರ ಎಂದರೆ ಪುರುಷಶ್ರೇಷ್ಠ ಎಂದರ್ಥ. ಭಗವಂತನ ಕಡೆಗೆ ತಮ್ಮ\nಮನಸ್ಸನ್ನು ಹರಿಯಗೊಟ್ಟವರು ಪುರುಷರು. ಅವರಲ್ಲಿ ಶ್ರೇಷ್ಠ-ಪುರುಷಶ್ರೇಷ್ಠ. ಅಂದರೆ ಜ್ಞಾನಿಗಳಲ್ಲಿ ಶ್ರೇಷ್ಠ\nಎಂದರ್ಥ. ನಾವೂ ಕೂಡಾ ನಮ್ಮ ಜೀವನದಲ್ಲಿ ಭರತಸತ್ತಮರು, ಪುರುಷವ್ಯಾಘ್ರರು ಆಗಬೇಕು. ಆಗ\nಭಗವಂತನ ಸಂದೇಶ ನಮಗೆ ತಲುಪುತ್ತದೆ.",
  "18.5": "ನಿಶ್ಚಯಮ್‌ ಶೃಣು ಮೇ ತತ್ರ ತ್ಯಾಗೇ ಭರತಸತ್ತಮ ।\nತ್ಯಾಗಃ ಹಿ ಪುರುಷವ್ಯಾಘ್ರ ತ್ರಿವಿಧಃ ಸಂಪ್ರಕೀರ್ತಿತಃ -- ಭರತಸತ್ತಮಾ, ಅದರಲ್ಲಿ ತ್ಯಾಗದ ಬಗ್ಗೆ ನನ್ನ ನಿರ್ಧಾರ\nಕೇಳು. ಪುರುಷವ್ಯಾಘ್ರಾ, ಮೂರು ಬಗೆಯ ತ್ಯಾಗ ಉಕ್ತವಾಗಿದೆ.\n\n“ತ್ಯಾಗದ ವಿಷಯದಲ್ಲಿ ನಿಶ್ಚಿತವಾದ ಅಭಿಪ್ರಾಯವನ್ನು ನಿನಗೆ ಹೇಳುತ್ತೇನೆ” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಹೇಗೆ ಯಜ್ಞ-\nದಾನ-ತಪಸ್ಸು ಮೂರು ವಿಧವೋ ಹಾಗೇ ತ್ಯಾಗವೂ ಕೂಡಾ ಮೂರು ವಿಧ. ಅದನ್ನು ಕೃಷ್ಣ ಅರ್ಜುನನಿಗೆ\nವಿವರಿಸುತ್ತಾನೆ. ಇಲ್ಲಿ ಕೃಷ್ಣ ಅರ್ಜುನನನ್ನು ಭರತಸತ್ತಮ ಮತ್ತು ಪುರುಷವ್ಯಾಘ್ರ ಎಂದು ಸಂಬೋಧಿಸಿದ್ದಾನೆ.\nಭರತವಂಶದ ಅರಸರ ಮಾಲಿಕೆಯಲ್ಲಿ ಗಣ್ಯನಾದ್ದರಿಂದ ಅರ್ಜುನ ಭರತಸತ್ತಮ-ಇದು ಮೇಲ್ನೋಟದ ಅರ್ಥ.\nಭಗವಂತನಲ್ಲಿ ಮತ್ತು ಜ್ಞಾನದಲ್ಲಿ ರತನಾದವ, ಭಕ್ತಿ ಉಳ್ಳವ ಭರತಸತ್ತಮ ಎನ್ನುವುದು ಈ ಸಂಬೋಧನೆಯ\nಅಂತರಂಗದ ಅರ್ಥ. ಅದೇ ರೀತಿ ಪುರುಷವ್ಯಾಘ್ರ ಎಂದರೆ ಪುರುಷಶ್ರೇಷ್ಠ ಎಂದರ್ಥ. ಭಗವಂತನ ಕಡೆಗೆ ತಮ್ಮ\nಮನಸ್ಸನ್ನು ಹರಿಯಗೊಟ್ಟವರು ಪುರುಷರು. ಅವರಲ್ಲಿ ಶ್ರೇಷ್ಠ-ಪುರುಷಶ್ರೇಷ್ಠ. ಅಂದರೆ ಜ್ಞಾನಿಗಳಲ್ಲಿ ಶ್ರೇಷ್ಠ\nಎಂದರ್ಥ. ನಾವೂ ಕೂಡಾ ನಮ್ಮ ಜೀವನದಲ್ಲಿ ಭರತಸತ್ತಮರು, ಪುರುಷವ್ಯಾಘ್ರರು ಆಗಬೇಕು. ಆಗ\nಭಗವಂತನ ಸಂದೇಶ ನಮಗೆ ತಲುಪುತ್ತದೆ.\n\nಯಜ್ಞದಾನತಪಃಕರ್ಮ ನ ತ್ಯಾಜ್ಯಂ ಕಾರ್ಯಮೇವ ತತ್‌ |\n\nಯಜ್ಞೋ ದಾನಂ ತಪಶ್ಚೈವ ಪಾವನಾನಿ ಮನೀಷಿಣಾಮ್‌ 1891\n\nಯಜ್ಞ ದಾನ ತಪಃ ಕರ್ಮ ನ ತ್ಯಾಜ್ಯಮ್‌ ಕಾರ್ಯಮ್‌ ಏವ ತತ್‌|\nಯಜ್ಞಃ ದಾನಮ್‌ ತಪಃ ಚ ಏವ ಪಾವನಾನಿ ಮನೀಷಿಣಾಮ್‌ - ಯಜ್ಞ-ದಾನ-ತಪಗಳೆಂಬ ಕರ್ಮವನ್ನು\nಬಿಡಲಾಗದು. ಅದನ್ನು ಮಾಡಲೇಬೇಕು. ಯಜ್ಞ, ದಾನ, ತಪಸ್ಸು ಜ್ಞಾನಿಗಳನ್ನು ಪಾವನಗೊಳಿಸುತ್ತದೆ.\n\nಯಾವಾಗಲೂ ಭಗವಂತನ ಆರಾಧನಾ ರೂಪವಾದ ಯಜ್ಞ, ದಾನ, ತಪವನ್ನು ಬಿಡಬಾರದು. ಅದನ್ನು\nಮಾಡಲೇಬೇಕು. ಇದಕ್ಕಿಂತ ಮಂಗಳವಾದ ಸಂಗತಿ ಇನ್ನೊಂದಿಲ್ಲ. ಇವು ಮೂರೂ ಕೂಡಾ ನಮ್ಮ ಬದುಕನ್ನು\nಪವಿತ್ರಗೊಳಿಸುವ ಕ್ರಿಯೆಗಳು. ಇದಕ್ಕಿಂತ ಹೆಚ್ಚು ಪವಿತ್ರವಾದ ಕ್ರಿಯೆ ಇನ್ನೊಂದು ಜಗತ್ತಿನಲ್ಲಿಲ್ಲ. ಇತರ ಎಲ್ಲಾ\nಕ್ರಿಯೆಗಳೂ ಈ ಮೂರು ಕ್ರಿಯೆಯಲ್ಲಿ ಅಂತರ್ಭಾವವಾಗಿರುತ್ತವೆ. ಆದ್ದರಿಂದ ನಮ್ಮ ಜೀವನದ ಪ್ರತಿಯೊಂದು\nಕ್ರಿಯೆ ಕೂಡಾ ಯಜ್ಞ-ದಾನ-ತಪವಾಗಬೇಕು.",
  "18.6": "ಏತಾನಿ ಅಪಿ ತು ಕರ್ಮಾಣಿ ಸಂಗಮ್‌ ತ್ಯಕ್ತ್ವಾ ಫಲಾನಿ ಚ ।\nಕರ್ತವ್ಯಾನಿ ಇತಿ ಮೇ ಪಾರ್ಥ ನಿಶ್ಚಿತಮ್‌ ಮತಮ್‌ ಉತ್ತಮಮ್‌ - ಆದರೆ, ಪಾರ್ಥಾ, ಈ ಕರ್ಮಗಳನ್ನು ಮಮತೆ\nತೊರೆದು, ಫಲದ ಹಂಬಲ ತೊರೆದು ಮಾಡಬೇಕು ಎನ್ನುವುದು ನನ್ನ ಖಚಿತವಾದ ಮತ್ತು ಹಿರಿದಾದ ಆಶಯ.\n\nಕರ್ಮ ಮಾಡುವಾಗ ಅದರಲ್ಲಿ ಬರುವ ಮೂಲ ದೋಷ \"ನಾನು ಮಾಡಿದೆ, ನನ್ನಿಂದಾಯಿತು' ಎನ್ನುವ ಅಹಂಕಾರ.\nಇದರ ಜೊತೆಗೆ ದೇವರ ಬಳಿ ನಮ್ಮ ಫಲಕಾಮನೆಯ ಪಟ್ಟಿ ಕೊಟ್ಟು ಫಲಾಪೇಕ್ಷೆಯಿಂದ ಕರ್ಮ ಮಾಡುವುದು.\nಇವು. ಕರ್ಮದಲ್ಲಿನ ಮಹಾದೋಷ. ಅಹಂಕಾರದಿಂದ ಕರ್ಮ ಮಾಡಿದರೆ ಅದು ವ್ಯರ್ಥ -ಬಏಕೆಂದರೆ\nಅಹಂಕಾರವಿದ್ದೆಡೆಗೆ ಭಗವಂತ ಬರಲಾರ. ಇನ್ನು ನಾವು ಫಲದ ಅಸೆಯಿಂದ ಕರ್ಮ ಮಾಡುವುದು.\nಫಲದಾಸೆಯಿಂದ ಕರ್ಮ ಮಾಡಿ ಒಂದು ವೇಳೆ ನಾವು ಬಯಸಿದ ಫಲ ನೆರವೇರದಿದ್ದರೆ, ಆಗ ನಮಗೆ ಆ\nಕರ್ಮದಲ್ಲಿ ಆಸಕ್ತಿ ದೂರವಾಗುತ್ತದೆ. ದೇವರ ಬಗ್ಗೆ ವೈರತ್ವ ಉಂಟಾಗುತ್ತದೆ. ಇದು ಫಲಾಪೇಕ್ಷೆಯಿಂದ ಕರ್ಮ\nಮಾಡುವುದರಿಂದ ಆಗುವ ಅನಾಹುತ. “ಇದು ನನ್ನ ನಿಶ್ಚಿತವಾದ ಅಭಿಪ್ರಾಯ. ನೀನು ಬಿಡಬೇಕಾದದ್ದು\nಕರ್ಮವನ್ನಲ್ಲ, ಬದಲಿಗೆ ಕರ್ಮಫಲವನ್ನು ಮತ್ತು ನಾನು ಮಾಡಿದೆ ಎನ್ನುವ ಆಸಕ್ತಿ-ಅಹಂಕಾರವನ್ನು” ಎನ್ನುತ್ತಾನೆ\nಕೃಷ್ಣ... ಇದು. ಕರ್ಮ ಸಿದ್ಧಾಂತದ ಅತ್ಯಂತ ಶ್ರೇಷ್ಠ ತೀರ್ಮಾನ. ಅಹಂಕಾರವನ್ನು,\nಕಾಮ್ಯಕರ್ಮವನ್ನು(ಫಲಕ್ಕಾಗಿಯೇ ಕರ್ಮ ಮಾಡುವುದನ್ನು) ಮತ್ತು ಕರ್ಮದಲ್ಲಿ ಫಲವನ್ನು ಬಯಸುವುದನ್ನು-\nಬಿಡುವುದು ನಿಜವಾದ ತ್ಯಾಗವೇ ಹೊರತು, ನಿಯತಕರ್ಮವನ್ನು ಬಿಡುವುದಲ್ಲ. ಇದು ನಿಶ್ಚಿತವಾದ ಸಿದ್ಧಾಂತ.\n\nನಿಯತಸ್ಯ ತು ಸಂನ್ಯಾಸಃ ಕರ್ಮಣೋ ನೋಪಪದ್ಯತೇ |\nಮೋಹಾತ್‌ ತಸ್ಯ ಪರಿತ್ಯಾಗಸ್ತಾಮಸಃ ಪರಿಕೀರ್ತಿತಃ 1೭॥\n\nನಿಯತಸ್ಯ ತು ಸಂನ್ಯಾಸಃ ಕರ್ಮಣಃ ನ ಉಪಪದ್ಯತೇ |\nಮೋಹಾತ್‌ ತಸ್ಯ ಪರಿತ್ಯಾಗಃ ತಾಮಸಃ ಪರಿಕೀರ್ತಿತಃ - ವಿಹಿತವಾದ ಕರ್ಮವನ್ನು ತೊರೆಯುವುದು ತರವಲ್ಲ.\nಅರಿವುಗೆಟ್ಟು ಅದನ್ನು ತೊರೆವುದು ತಾಮಸ ತ್ಯಾಗ ಎನಿಸುತ್ತದೆ.\n\nಯಾವ ಕಾಲಕ್ಕೂ ನಾವು ನಮ್ಮ ನಿಯತಕರ್ಮವನ್ನು ತೊರೆಯಬಾರದು. ಒಂದು ವೇಳೆ ತಪ್ಪು ತಿಳುವಳಿಕೆಯಿಂದ\nನಿಯತ ಕರ್ಮವನ್ನು ಬಿಟ್ಟರೆ ಆಗ ಅದು ತಾಮಸ ತ್ಯಾಗ ಎನಿಸುತ್ತದೆ. ಇಲ್ಲಿ 'ನಿಯತಕರ್ಮ' ಎಂದರೆ ನಮ್ಮ\nಜೀವಯೋಗ್ಯತೆಗೆ ಯಾವುದು ನಿಯತವೋ ಆ ಕರ್ಮ. ನಮಗೆ ತಿಳಿದಂತೆ ಎಲ್ಲಾ ಕರ್ಮವನ್ನು ಎಲ್ಲರೂ\nಮಾಡುವಂತಿಲ್ಲ. ಉದಾಹರಣೆಗೆ ಯಜ್ಞ: ಯತಿಗಳು ಅಗ್ನಿಮುಖದಲ್ಲಿ ಆಹುತಿ ನೀಡುವಂತಿಲ್ಲ; ಬ್ರಹ್ಮಚಾರಿಗಳು\nಪೂರ್ಣಪ್ರಮಾಣದ ಅಗ್ನಿಹೋತ್ರ ಮಾಡುವಂತಿಲ್ಲ. ಆದರೆ ಯತಿಗಳು ಜ್ಞಾನಯಜ್ಞ ಮಾಡಬಹುದು ಅದು ಅವರ\nನಿಯತಕರ್ಮ. ಎಲ್ಲಾ ಕಾಲದಲ್ಲೂ ಎಲ್ಲರೂ ಮಾಡಬಹುದಾದ ಯಜ್ಞ 'ನಾಮಯಜ್ಞ'. ಅಂದರೆ ಭಗವಂತನ ನಾಮ\nಸ್ಮರಣೆ. ಇದು ಯಜ್ಞದಲ್ಲಿ ಎಲ್ಲರಿಗೂ ಅನ್ವಯಿಸುವ ನಿಯತಕರ್ಮ. ಇನ್ನು ದಾನ: ಬ್ರಹ್ಮಚಾರಿಗಳು ಕನ್ಯಾದಾನ\nಮಾಡಲಾಗುವುದಿಲ್ಲ, ಅದನ್ನು ಗೃಹಸ್ಥ ಮಾಡಬೇಕು. ಗೃಹಸ್ಥನಿಗೆ ಕನ್ಯಾದಾನ ನಿಯತಕರ್ಮ. ಎಲ್ಲರೂ\nಮಾಡಬಹುದಾದ ದಾನ-ಅಭಯದಾನ ಮತ್ತು ಜ್ಞಾನದಾನ. ಮೂರನೆಯದು ತಪಸ್ಸು: ಕೆಲವು ತಪಸ್ಸನ್ನು\nಎಲ್ಲರೂ ಮಾಡಲಾಗುವುದಿಲ್ಲ. ಅದಕ್ಕೆ ವೇದಧೀಕ್ಷೆ ಬೇಕಾಗಬಹುದು. ಆದರೆ ಎಲ್ಲರೂ ಮಾಡಬಹುದಾದ ತಪಸ್ಸು\nಎಂದರೆ ಉಪವಾಸಾದಿ ವೃತಾನುಷ್ಠಾನಗಳು. ಈ ತಪಸ್ಸನ್ನು ಮನುಷ್ಯ ಮಾತ್ರದವರು ಮಾಡಬಹುದು. ಹೀಗೆ\nಯಾರಿಗೆ ಯಾವ ಕರ್ಮ ನಿಯತವೋ ಆ ಕರ್ಮವನ್ನು ಮಾಡಬೇಕು. ನಿಯತ ಕರ್ಮದಲ್ಲಿ ಫಲಾಪೇಕ್ಷೆಯ\nಪ್ರಶ್ನೆಯೇ ಇಲ್ಲ. ತಪ್ಪು ತಿಳುವಳಿಕೆಯಿಂದ ನಿಯತಕರ್ಮವನ್ನು ಬಿಟ್ಟರೆ ಅದು ತಾಮಸ ತ್ಯಾಗ ಎನಿಸುತ್ತದೆ\nಎನ್ನುವ ಎಚ್ಚರವನ್ನು ಕೃಷ್ಣ ಈ ಶ್ಲೋಕದ ಮೂಲಕ ಕೊಟ್ಟಿದ್ದಾನೆ.\n\nದುಃಖಮಿತ್ಯೇವ ಯತ್‌ ಕರ್ಮ ಕಾಯಕ್ಷೇಶಭಯಾತ್‌ ತ್ಯಜೇತ್‌ |\n\nಸ ಕೃತ್ವಾ ರಾಜಸಂ ತ್ಯಾಗಂ ನೈವ ತ್ಯಾಗಫಲಂ ಲಭೇತ್‌",
  "18.7": "ಕರ್ಮ ಮಾಡುವಾಗ ಅದರಲ್ಲಿ ಬರುವ ಮೂಲ ದೋಷ \"ನಾನು ಮಾಡಿದೆ, ನನ್ನಿಂದಾಯಿತು' ಎನ್ನುವ ಅಹಂಕಾರ.\nಇದರ ಜೊತೆಗೆ ದೇವರ ಬಳಿ ನಮ್ಮ ಫಲಕಾಮನೆಯ ಪಟ್ಟಿ ಕೊಟ್ಟು ಫಲಾಪೇಕ್ಷೆಯಿಂದ ಕರ್ಮ ಮಾಡುವುದು.\nಇವು. ಕರ್ಮದಲ್ಲಿನ ಮಹಾದೋಷ. ಅಹಂಕಾರದಿಂದ ಕರ್ಮ ಮಾಡಿದರೆ ಅದು ವ್ಯರ್ಥ -ಬಏಕೆಂದರೆ\nಅಹಂಕಾರವಿದ್ದೆಡೆಗೆ ಭಗವಂತ ಬರಲಾರ. ಇನ್ನು ನಾವು ಫಲದ ಅಸೆಯಿಂದ ಕರ್ಮ ಮಾಡುವುದು.\nಫಲದಾಸೆಯಿಂದ ಕರ್ಮ ಮಾಡಿ ಒಂದು ವೇಳೆ ನಾವು ಬಯಸಿದ ಫಲ ನೆರವೇರದಿದ್ದರೆ, ಆಗ ನಮಗೆ ಆ\nಕರ್ಮದಲ್ಲಿ ಆಸಕ್ತಿ ದೂರವಾಗುತ್ತದೆ. ದೇವರ ಬಗ್ಗೆ ವೈರತ್ವ ಉಂಟಾಗುತ್ತದೆ. ಇದು ಫಲಾಪೇಕ್ಷೆಯಿಂದ ಕರ್ಮ\nಮಾಡುವುದರಿಂದ ಆಗುವ ಅನಾಹುತ. “ಇದು ನನ್ನ ನಿಶ್ಚಿತವಾದ ಅಭಿಪ್ರಾಯ. ನೀನು ಬಿಡಬೇಕಾದದ್ದು\nಕರ್ಮವನ್ನಲ್ಲ, ಬದಲಿಗೆ ಕರ್ಮಫಲವನ್ನು ಮತ್ತು ನಾನು ಮಾಡಿದೆ ಎನ್ನುವ ಆಸಕ್ತಿ-ಅಹಂಕಾರವನ್ನು” ಎನ್ನುತ್ತಾನೆ\nಕೃಷ್ಣ... ಇದು. ಕರ್ಮ ಸಿದ್ಧಾಂತದ ಅತ್ಯಂತ ಶ್ರೇಷ್ಠ ತೀರ್ಮಾನ. ಅಹಂಕಾರವನ್ನು,\nಕಾಮ್ಯಕರ್ಮವನ್ನು(ಫಲಕ್ಕಾಗಿಯೇ ಕರ್ಮ ಮಾಡುವುದನ್ನು) ಮತ್ತು ಕರ್ಮದಲ್ಲಿ ಫಲವನ್ನು ಬಯಸುವುದನ್ನು-\nಬಿಡುವುದು ನಿಜವಾದ ತ್ಯಾಗವೇ ಹೊರತು, ನಿಯತಕರ್ಮವನ್ನು ಬಿಡುವುದಲ್ಲ. ಇದು ನಿಶ್ಚಿತವಾದ ಸಿದ್ಧಾಂತ.\n\nನಿಯತಸ್ಯ ತು ಸಂನ್ಯಾಸಃ ಕರ್ಮಣೋ ನೋಪಪದ್ಯತೇ |\nಮೋಹಾತ್‌ ತಸ್ಯ ಪರಿತ್ಯಾಗಸ್ತಾಮಸಃ ಪರಿಕೀರ್ತಿತಃ 1೭॥\n\nನಿಯತಸ್ಯ ತು ಸಂನ್ಯಾಸಃ ಕರ್ಮಣಃ ನ ಉಪಪದ್ಯತೇ |\nಮೋಹಾತ್‌ ತಸ್ಯ ಪರಿತ್ಯಾಗಃ ತಾಮಸಃ ಪರಿಕೀರ್ತಿತಃ - ವಿಹಿತವಾದ ಕರ್ಮವನ್ನು ತೊರೆಯುವುದು ತರವಲ್ಲ.\nಅರಿವುಗೆಟ್ಟು ಅದನ್ನು ತೊರೆವುದು ತಾಮಸ ತ್ಯಾಗ ಎನಿಸುತ್ತದೆ.\n\nಯಾವ ಕಾಲಕ್ಕೂ ನಾವು ನಮ್ಮ ನಿಯತಕರ್ಮವನ್ನು ತೊರೆಯಬಾರದು. ಒಂದು ವೇಳೆ ತಪ್ಪು ತಿಳುವಳಿಕೆಯಿಂದ\nನಿಯತ ಕರ್ಮವನ್ನು ಬಿಟ್ಟರೆ ಆಗ ಅದು ತಾಮಸ ತ್ಯಾಗ ಎನಿಸುತ್ತದೆ. ಇಲ್ಲಿ 'ನಿಯತಕರ್ಮ' ಎಂದರೆ ನಮ್ಮ\nಜೀವಯೋಗ್ಯತೆಗೆ ಯಾವುದು ನಿಯತವೋ ಆ ಕರ್ಮ. ನಮಗೆ ತಿಳಿದಂತೆ ಎಲ್ಲಾ ಕರ್ಮವನ್ನು ಎಲ್ಲರೂ\nಮಾಡುವಂತಿಲ್ಲ. ಉದಾಹರಣೆಗೆ ಯಜ್ಞ: ಯತಿಗಳು ಅಗ್ನಿಮುಖದಲ್ಲಿ ಆಹುತಿ ನೀಡುವಂತಿಲ್ಲ; ಬ್ರಹ್ಮಚಾರಿಗಳು\nಪೂರ್ಣಪ್ರಮಾಣದ ಅಗ್ನಿಹೋತ್ರ ಮಾಡುವಂತಿಲ್ಲ. ಆದರೆ ಯತಿಗಳು ಜ್ಞಾನಯಜ್ಞ ಮಾಡಬಹುದು ಅದು ಅವರ\nನಿಯತಕರ್ಮ. ಎಲ್ಲಾ ಕಾಲದಲ್ಲೂ ಎಲ್ಲರೂ ಮಾಡಬಹುದಾದ ಯಜ್ಞ 'ನಾಮಯಜ್ಞ'. ಅಂದರೆ ಭಗವಂತನ ನಾಮ\nಸ್ಮರಣೆ. ಇದು ಯಜ್ಞದಲ್ಲಿ ಎಲ್ಲರಿಗೂ ಅನ್ವಯಿಸುವ ನಿಯತಕರ್ಮ. ಇನ್ನು ದಾನ: ಬ್ರಹ್ಮಚಾರಿಗಳು ಕನ್ಯಾದಾನ\nಮಾಡಲಾಗುವುದಿಲ್ಲ, ಅದನ್ನು ಗೃಹಸ್ಥ ಮಾಡಬೇಕು. ಗೃಹಸ್ಥನಿಗೆ ಕನ್ಯಾದಾನ ನಿಯತಕರ್ಮ. ಎಲ್ಲರೂ\nಮಾಡಬಹುದಾದ ದಾನ-ಅಭಯದಾನ ಮತ್ತು ಜ್ಞಾನದಾನ. ಮೂರನೆಯದು ತಪಸ್ಸು: ಕೆಲವು ತಪಸ್ಸನ್ನು\nಎಲ್ಲರೂ ಮಾಡಲಾಗುವುದಿಲ್ಲ. ಅದಕ್ಕೆ ವೇದಧೀಕ್ಷೆ ಬೇಕಾಗಬಹುದು. ಆದರೆ ಎಲ್ಲರೂ ಮಾಡಬಹುದಾದ ತಪಸ್ಸು\nಎಂದರೆ ಉಪವಾಸಾದಿ ವೃತಾನುಷ್ಠಾನಗಳು. ಈ ತಪಸ್ಸನ್ನು ಮನುಷ್ಯ ಮಾತ್ರದವರು ಮಾಡಬಹುದು. ಹೀಗೆ\nಯಾರಿಗೆ ಯಾವ ಕರ್ಮ ನಿಯತವೋ ಆ ಕರ್ಮವನ್ನು ಮಾಡಬೇಕು. ನಿಯತ ಕರ್ಮದಲ್ಲಿ ಫಲಾಪೇಕ್ಷೆಯ\nಪ್ರಶ್ನೆಯೇ ಇಲ್ಲ. ತಪ್ಪು ತಿಳುವಳಿಕೆಯಿಂದ ನಿಯತಕರ್ಮವನ್ನು ಬಿಟ್ಟರೆ ಅದು ತಾಮಸ ತ್ಯಾಗ ಎನಿಸುತ್ತದೆ\nಎನ್ನುವ ಎಚ್ಚರವನ್ನು ಕೃಷ್ಣ ಈ ಶ್ಲೋಕದ ಮೂಲಕ ಕೊಟ್ಟಿದ್ದಾನೆ.\n\nದುಃಖಮಿತ್ಯೇವ ಯತ್‌ ಕರ್ಮ ಕಾಯಕ್ಷೇಶಭಯಾತ್‌ ತ್ಯಜೇತ್‌ |\n\nಸ ಕೃತ್ವಾ ರಾಜಸಂ ತ್ಯಾಗಂ ನೈವ ತ್ಯಾಗಫಲಂ ಲಭೇತ್‌",
  "18.8": "ದುಃಖಮ್‌ ಇತಿ ಏವ ಯತ್‌ ಕರ್ಮ ಕಾಯ ಕ್ಲೇಶ ಭಯಾತ್‌ ತ್ಯಜೇತ್‌ |\n\nಸಃ ಕೃತ್ವಾ ರಾಜಸಮ್‌ ತ್ಯಾಗಮ್‌ ನ ಏವ ತ್ಯಾಗ ಫಲಮ್‌ ಲಭೇತ್‌ - ಮಾಡುವುದಕ್ಕೆ ಮೈಬಗ್ಗದೆ,\nಬಗೆಯೊಗ್ಗದೆ, ಕಷ್ಟವಾಗುತ್ತದೆ ಎಂದು ಮಾಡದೇ ಇರುವುದು ರಾಜಸ ತ್ಯಾಗ. ಇಂತಹ ತ್ಯಾಗ ಮಾಡಿಯೂ\nತ್ಯಾಗದ ಫಲ ದೊರೆಯದು.\n\nನಮಗೆ ನಮ್ಮ ನಿಯತಕರ್ಮ ಮಾಡಬೇಕು ಎನ್ನುವುದು ಗೊತ್ತಿದ್ದೂ, ಮನಸ್ಸಿಗೆ ದೇಹಕ್ಕೆ ನೋವಾಗುತ್ತದೆ ಎನ್ನುವ\nಕಾರಣಕ್ಕಾಗಿ ಕರ್ಮವನ್ನು ಮಾಡದೇ ಬಿಡುವುದು ರಾಜಸ ತ್ಯಾಗ ಎನಿಸುತ್ತದೆ. ಉದಾಹರಣೆಗೆ ಯಾವುದೋ\nದೂರದರ್ಶನದ ದಾರಾವಾಹಿಯನ್ನು ನೋಡಬೇಕು ಎನ್ನುವ ಮನಸ್ಸಿನ ಉತ್ಕಟ ಬಯಕೆಯಿಂದ ಕರ್ಮವನ್ನು\nಕೈಬಿಡುವುದು, ಚಳಿಯಾಗುತ್ತದೆ ಎಂದು ಸಂಧ್ಯಾವಂದನೆ ಮಾಡದೇ ಇರುವುದು, ಇತ್ಯಾದಿ ರಾಜಸ ತ್ಯಾಗ.\nಇಂತಹ ರಾಜಸ ತ್ಯಾಗ ಮಾಡಿದರೆ ನಿಜವಾದ ತ್ಯಾಗದ ಫಲ ಸಿಗದು.\n",
  "18.9": "ಕಾರ್ಯಮ್‌ ಇತಿ ಏವ ಯತ್‌ ಕರ್ಮ ನಿಯತಮ್‌ ಕ್ರಿಯತೇ ಅರ್ಜುನ |\n\nಸಂಗಂ ತ್ಯಕ್ತ್ವಾ ಫಲಂ ಚ ಏವ ಸಃ ತ್ಯಾಗಃ ಸಾತ್ರ್ವಿಕಃ ಮತಃ - ಅರ್ಜುನಾ, ಕರ್ತವ್ಯ ದೃಷ್ಟಿಯಿಂದ ವಿಹಿತ\nಕರ್ಮವನ್ನು ಮಾಡುತ್ತಲೇ ಮಮತೆಯನ್ನೂ ಫಲದ ಹಂಬಲವನ್ನೂ ತೊರೆಯುವುದು ಸಾತ್ತ್ವಿಕ ತ್ಯಾಗ\nಎನಿಸುತ್ತದೆ.\n\nನಿಯತಕರ್ಮವನ್ನು ಮಾಡದೇ ಇರಲು ಸಾಧ್ಯವಿಲ್ಲ ಎನ್ನುವ ಮಟ್ಟಕ್ಕೆ ನಮ್ಮ ಮನಸ್ಸು ತಲುಪಬೇಕು. ಈ ರೀತಿ\nಸತ್ತ್ವಗುಣ ಮನಸ್ಸಿನಲ್ಲಿ. ತುಂಬಿದಾಗ(ಅರ್ಜುನರಾದಾಗ್ರಿಯಾವ ಕರ್ಮವನ್ನೂ ಬಿಡಲು ನಮಗೆ\nಮನಸ್ಸಾ ಗುವುದಿಲ್ಲ. ಅಲ್ಲಿ ಫಲದ ಬಯಕೆ ಇರುವುದೇ ಇಲ್ಲ. ಸದಾ ಭಗವದರ್ಪಣ ಭಾವನೆಯಲ್ಲಿ ಖುಷಿಯಿಂದ\nಕರ್ಮ ಮಾಡುವುದು; ಯಾವುದೇ ಅಹಂಕಾರ ಇಲ್ಲದೇ ಇರುವುದು; ಎಲ್ಲಾ ಕರ್ಮದ ಮಹತ್ವ ತಿಳಿದು\nನಿಯತವಾಗಿ ಕರ್ಮ ಮಾಡುವುದು- ಸಾತ್ತ್ವಿಕತ್ಯಾಗ. ಇಲ್ಲಿ ತ್ಯಾಗ ಮಾಡುವುದು ಕರ್ಮವನ್ನಲ್ಲ ಬದಲಿಗೆ ಕರ್ಮ\nಫಲವನ್ನು.\nಹೀಗೆ ನಮ್ಮಲ್ಲಿರುವ ಗೊಂದಲಗಳಿಗೆ ಕೃಷ್ಣ ಅತ್ಯಂತ ಸರಳವಾದ ಉತ್ತರ ಕೊಟ್ಟ. ಒಟ್ಟಿನಲ್ಲಿ ಹೇಳಬೇಕೆಂದರೆ:\nಫಲಾಪೇಕ್ಷೆ ಇಲ್ಲದೆ. ಅಹಂಕಾರ ತೊರೆದು. ನಿಯತಕರ್ಮವನ್ನು ಮಾಡುವುದು ಸಾತ್ತ್ವಿಕ ತ್ಯಾಗ;\nಸೋಮಾರಿತನದಿಂದ ಕಷ್ಟವಾಗುತ್ತದೆ ಎಂದು ನಿಯತಕರ್ಮವನ್ನು ಬಿಡುವುದು ರಾಜಸ ತ್ಯಾಗ ಮತ್ತು ತಪ್ಪು\nತಿಳುವಳಿಕೆಯಿಂದ, “ಎಲ್ಲವೂ ಮೂಢನಂಬಿಕೆ' ಎಂದು ನಿಯತಕರ್ಮವನ್ನು ಮಾಡದೇ ಬಿಡುವುದು ತಾಮಸ\nತ್ಯಾಗ.\n",
  "18.10": "ನ ದ್ವೇಷ್ಟಿ ಅಕುಶಲಮ್‌ ಕರ್ಮ ಕುಶಲೇ ನ ಅನುಷಜ್ಜತೇ |\n\nತ್ಯಾಗೀ ಸತ್ತ್ವಸಮಾವಿಷ್ಟಃ ಮೇಧಾವೀ ಛಿನ್ನಸಂಶಯಃ - ಮುದ ನೀಡದ ಕರ್ಮದ ಬಗ್ಗೆ ಹಗೆಯೂ ಇಲ್ಲ, ಮುದ\nನೀಡುವ ಕರ್ಮದ ಬಗ್ಗೆ ಅತಿಯಾದ ನಂಟೂ ಇಲ್ಲ. ಇಂತವನು ಸಾತ್ವಿಕ-ತ್ಯಾಗಿ. ಅವನು ತಿಳಿದವನು ಮತ್ತು\nಸಂದೇಹವಳಿದವನು.\n\nಈ ಶ್ಲೋಕ ಒಬ್ಬ ಸಾತ್ವಿಕ ತ್ಯಾಗಿ ಯಾವ ರೀತಿ ತನ್ನ ಕರ್ಮಗಳನ್ನು ನೋಡುತ್ತಾನೆ ಎನ್ನುವುದನ್ನು ಹೇಳುತ್ತದೆ.\nನಾವು ಮಾಡಿದ ಹಿಂದಿನ ಯಾವುದೋ ಒಂದು ಕರ್ಮದಿಂದ ಇಂದು ಕೆಟ್ಟ ಪರಿಣಾಮ ಆಗುತ್ತಿದ್ದರೆ, ಅಥವಾ\nಹಿಂದೆ ಮಾಡಿದ ಇನ್ಯಾವುದೋ ಕರ್ಮದಿಂದ ಒಳ್ಳೆಯದು ಆಗುತ್ತಿದ್ದರೆ, ಸಾತ್ವಿಕ ತ್ಯಾಗಿ ಅದರ ಬಗ್ಗೆ\nತಲೆಕೆಡಿಸಿಕೊಳ್ಳುವುದಿಲ್ಲ. ಆತ ಒಳ್ಳೆಯದಾಯಿತು. ಎಂದು ಹಾರಾಡುವುದಿಲ್ಲ, ಕೆಟ್ಟದ್ದಾಯಿತು ಎಂದು\nಕುಸಿಯುವುದಿಲ್ಲ. ಈತ ದುಃಖಕಾರಕವಾದ ಕರ್ಮವನ್ನು ದ್ವೇಷಿಸುವುದೂ ಇಲ್ಲ. ಔಷಧಿ ಹೇಗೆ ಕಹಿ ಇರುತ್ತದೋ\nಹಾಗೇ ಸತ್ಕರ್ಮ ಕಿಂಚಿತ್‌ ದುಃಖಕರವಾದಾಗ ಅದರ ಬಗ್ಗೆ ಆತ ಚಿಂತೆ ಮಾಡುವುದಿಲ್ಲ.\n\nಸಾತ್ವಿಕ ತ್ಯಾಗಿಯ ಮನಸ್ಸು ಸತ್ತ್ವಗುಣದಲ್ಲಿ ತುಂಬಿರುತ್ತದೆ. ಅವನಿಗೆ ತಾಮಸ-ರಾಜಸ ಚಿಂತೆಗಳೇ\nಬರುವುದಿಲ್ಲ. ಬಲಜ್ಜ್ಞಾನಗಳಿಂದ ಪರಿಪೂರ್ಣನಾದ ಭಗವಂತನಲ್ಲಿ ಎಲ್ಲವನ್ನೂ ಅರ್ಪಿಸಿ ಆತ ಕರ್ಮ\n\nಮಾಡುತ್ತಿರುತ್ತಾನೆ. ಇದರಿಂದ ಆತನ ಮನಸ್ಸು ಪೂರ್ಣವಾಗಿ ಭಗವಂತನಲ್ಲಿ ಸಮಾವಿಷ್ಠವಾಗಿರುತ್ತದೆ.\nಮೇಧಾವಿಯಾಗಿರುವ ಈತನಿಗೆ ತನ್ನ ಬದುಕಿನ ಪ್ರತೀ ನಡೆಯ ಎಚ್ಚರವಿರುತ್ತದೆ. ಭಗವಂತನಲ್ಲಿ ನೆಲೆಗೊಂಡ\nಇಂತವರ ಮನಸ್ಸಿಗೆ ಎಂದೂ ಯಾವ ಗೊಂದಲವೂ ಸುಳಿಯುವುದಿಲ್ಲ. ಇಂತವರ ಜೀವನದ ನಡೆ ನೋಡಲು\nಸಾಮಾನ್ಯವಾಗಿರುತ್ತದೆ ಆದರೆ ಅವರ ಕ್ರಿಯೆಯ ಹಿಂದಿನ ಅನುಸಂಧಾನ ಮಾತ್ರ ಭಿನ್ನವಾಗಿರುತ್ತದೆ. ಇವರು\n“ಭಗವಂತ ನೀನು ಮಾಡಿಸುತಿದ್ದಿ-ನಾನು ಮಾಡುತ್ತಿದ್ದೇನೆ” ಎನ್ನುವ ಅನುಸಂಧಾನದಿಂದ ತಮ್ಮ ಕರ್ಮವನ್ನು\nಮಾಡುತ್ತಿರುತ್ತಾರೆ.\n",
  "18.11": "ನಹಿ ದೇಹಭೃತಾ ಶಕ್ಯಂ ತ್ಯಕ್ತುಂ ಕರ್ಮಾಣಿ ಅಶೇಷತಃ ।\nಯಃ ತು ಕರ್ಮ ಫಲ ತ್ಯಾಗೀ ಸಃ ತ್ಯಾಗೀ ಇತಿ ಅಭಿಧೀಯತೇ -ಶರೀರದಲ್ಲಿರುವಷ್ಟು ಕಾಲ ಕರ್ಮಗಳನ್ನು\nಪೂರ್ತಿಯಾಗಿ ಬಿಡುವುದು ಸಾಧ್ಯವಿಲ್ಲ. ಕರ್ಮದ ಫಲವನ್ನು ತೊರೆದವನೇ ಕರ್ಮತ್ಯಾಗಿ.\n\nಮನುಷ್ಯನಾಗಿ ಹುಟ್ಟಿದ ಮೇಲೆ, ಹುಟ್ಟಿನಿಂದ ಸಾಯುವ ತನಕ ನಾವು ಕರ್ಮ ಮಾಡಲೇ ಬೇಕು. ಕರ್ಮವನ್ನೆ ತ\nಬಿಟ್ಟು ಬದುಕಲು ಸಾಧ್ಯವಿಲ್ಲ. ನಾವು ತೊರೆಯಬೇಕಾದದ್ದು ಕರ್ಮವನ್ನ ಲ್ಲ-ಕರ್ಮಫಲವನ್ನು . ಈ ರೀತಿ ಕರ್ಮ\nಮಾಡಿಕೊಂಡು ಕರ್ಮಫಲ ತೊರೆದವನು ಕರ್ಮತ್ಯಾಗಿ ಎನಿಸುತ್ತಾನೆ.\n",
  "18.12": "ಅನಿಷ್ಟಮ್‌ ಇಷ್ಟಂ ಮಿಶ್ರಂ ಚ ತ್ರಿವಿಧಂ ಕರ್ಮಣಃ ಫಲಮ್‌ ।\nಭವತಿ ಅತ್ಯಾಗಿನಾಂ ಪ್ರೇತ್ಯ ನತು ಸಂನ್ಯಾಸಿನಾಂ ಕ್ವಚಿತ್‌ - ಕರ್ಮದ ಫಲ ಮೂರು ತೆರ: ಬೇಕಾದ್ದು,\nಬೇಡವಾದದ್ದು, ಮತ್ತು ಎರಡರ ಬೆರಕೆ. ಫಲತ್ಯಾಗ ಮಾಡದವರಿಗೆ ಇದು ಸತ್ತಮೇಲೆ ಸಲ್ಲುತ್ತದೆ. ಫಲದ ನಂಟು\n\nತೊರೆದವರಿಗೆ ಇದು ಎಂದೂ ಸೋಕುವುದಿಲ್ಲ.\n\nಕರ್ಮ ಮಾಡುವುದರಿಂದ ಸುಖವಾಗಬಹುದು; ದುಃಖವಾಗಬಹುದು; ಅಥವಾ ಸುಖ-ದುಃಖದ ಬೆರಕೆಯ ಫಲ\nಸಿಗಬಹುದು. ಕರ್ಮಫಲ ತ್ಯಾಗ ಮಾಡದೇ ಕರ್ಮ ಮಾಡುವವರಿಗೆ ಇದು ಸತ್ತ ಮೇಲೆ ಸಲ್ಲುತ್ತದೆ. ಇವರು ಕರ್ಮ\nಮತ್ತು ಕರ್ಮ ಫಲದ ಸುಳಿಯಲ್ಲಿ ಸಿಲುಕಿ ಮತ್ತೆ ಸಂಸಾರ ಬಂಧದಲ್ಲಿ ಸಿಲುಕುತ್ತಾರೆ. ಆದರೆ ಕರ್ಮ ಫಲದ\nಅಪೇಕ್ಷೆ ಇಲ್ಲದವರಿಗೆ ಇದು ಎಂದೂ ಸೋಕುವುದಿಲ್ಲ. ಅವರಿಗೆ ಏನು ಬಂದರೂ ಅದು ಭಗವಂತನ ಪ್ರಸಾದ.\nಅದರಲ್ಲಿ ಬೇಕಾದ್ದು, ಬೇಡವಾದದ್ದು ಎನ್ನು ವ ಭೇದವಿಲ್ಲ. ಇದು ಮೋಕ್ಷ ಮಾರ್ಗ. ಉದಾಹರಣೆಗೆ ರಾಜ್ಯದ,\nಅಧಿಕಾರದ ಆಸೆಯಿಂದ, ಭಗವಂತನನ್ನು ಮರೆತು ಯುದ್ಧವನ್ನು ಮಾಡುವವ- ಯುದ್ಧದಲ್ಲಿ ನಡೆಯುವ\n\nಪ್ರಾಣಹಾನಿಗೆ ಕಾರಣನಾಗುತ್ತಾನೆ. ಆತ ಈ ಪಾಪದ ಹೊರೆಯನ್ನು ಸತ್ತ ನಂತರ ಪಡೆಯಬೇಕಾಗುತ್ತದೆ. ಆದರೆ\nಕರ್ತವ್ಯ ಕಾರಣಕ್ಕಾಗಿ ಯಾವುದೇ ಸ್ವಾರ್ಥವಿಲ್ಲದೆ ಎಲ್ಲವನ್ನೂ ಭಗವಂತನಿಗೆ ಅರ್ಪಿಸಿ ಯುದ್ಧ ಮಾಡುವವನಿಗೆ\nಯಾವ ಪಾಪದ ಲೇಪವೂ ಅಂಟುವುದಿಲ್ಲ.\n",
  "18.13": "ಪಂಚ ಏತಾನಿ ಮಹಾಬಾಹೋ ಕಾರಣಾನಿ ನಿಬೋಧ ಮೇ |\n\nಸಾಂಖ್ಯೇ ಕೃತ ಅಂತೇ ಪ್ರೋಕ್ತಾನಿ ಸಿದ್ಧಯೇ ಸರ್ವ ಕರ್ಮಹಾಮ್‌ -ಎಲ್ಲಾ ಕಾರ್ಯಗಳು ಕೈಗೂಡಲು ಇವು ಐದು\nಕಾರಣಗಳು. ಹೇ ಮಹಾಬಾಹೋ, ವೈದಿಕ ಜ್ಞಾನದ ಸಿದ್ಧಾಂತದಲ್ಲಿ ಹೇಳಲಾದ ಅವುಗಳನ್ನು ನನ್ನಿಂದ\nತಿಳಿದುಕೋ :\n\nನಮ್ಮಲ್ಲಿ ಅನೇಕರಿಗೆ ಒಂದು ಪ್ರಶ್ನೆ ಇದೆ. ನಾವು ಮಾಡಿದ ಕೆಲಸವನ್ನು “ನಾನು ಮಾಡಿದೆ' ಅನ್ನುವುದರಲ್ಲಿ\nತಪ್ಪೇನು' ಎಂದು. ಈ ಪ್ರಶ್ನೆಗೆ ನಾವು ಉತ್ತರ ಕಂಡುಕೊಳ್ಳಬೇಕಾದರೆ, ಒಂದು ಕ್ರಿಯೆ ನಡೆಯಬೇಕಾದರೆ ಆ\nಕ್ರಿಯೆಯ ಹಿಂದೆ ಇರುವ ಐದು ಕಾರಣಗಳನ್ನು ತಿಳಿದುಕೊಳ್ಳಬೇಕು. ವೈದಿಕ ಸಾಂಖ್ಯ ಶಾಸ್ತ್ರದಲ್ಲಿ, ಜ್ಞಾನದ\nಸಿದ್ಧಾಂತದಲ್ಲಿ ಹೇಳಲಾದ ಈ ಐದು ಕಾರಣಗಳನ್ನು ಕೃಷ್ಣ ಅರ್ಜುನನಿಗೆ ವಿವರಿಸುತ್ತಾನೆ.\n\nಇಲ್ಲಿ ಕೃಷ್ಣ ಅರ್ಜುನನನ್ನು ಮಹಾಬಾಹೋ ಎಂದು ಸಂಬೋಧಿಸಿದ್ದಾನೆ. 'ಮಹಾ-ಬ' ಅಂದರೆ ಮಹತ್ತಾದ\nಬಯಕೆಗಳು. ಅದನ್ನು ತ್ಯಾಗ ಮಾಡಿದವ-ಮಹಾಬಾಹು. ನಾವೆಲ್ಲರೂ ನಮ್ಮ ಜೀವನದಲ್ಲಿ ಕರ್ಮಫಲತ್ಯಾಗ\nಮಾಡಿ, . ಕೇವಲ... ಭಗವದರ್ಪಣಾ ಭಾವದಿಂದ. ಕರ್ಮ ಮಾಡುವುದನ್ನು ಕಲಿತುಕೊಂಡು-\n\nಮಹಾಬಾಹುಗಳಾಗಬೇಕು ಎನ್ನುವುದು ಈ ಸಂಬೋಧನೆಯ ಹಿಂದಿರುವ ಧ್ವನಿ.",
  "18.14": "ಅಧಿಷ್ಠಾನಂ ತಥಾ ಕರ್ತಾ ಕರಣಂ ಚ ಪೃಥಗ್‌ ವಿಧಮ್‌ ।\n\nವಿವಿಧಾಃ ಚ ಪೃಥಕ್‌ ಚೇಷ್ಟಾಃ ದೈವಂ ಚ ಏವ ಅತ್ರ ಪಂಚಮಮ್‌ - ಕ್ರಿಯೆ ನಡೆಯುವ ತಾಣ, ಮಾಡುವ\nಭಗವಂತ [ಜೀವ], ಬೇರೆಬೇರೆ ಉಪಕರಣಗಳು, ಬಗೆಬಗೆಯ ಪೂರಕ ಕ್ರಿಯೆಗಳು ಮತ್ತು ಐದನೆಯದಾದ\nಅದೃಷ್ಟ[ಭಗವಂತ].\n\nಪ್ರತಿಯೊಂದು ಕ್ರಿಯೆ ನಡೆಯಲು ಐದು ಕಾರಣಗಳು:\n\n(೧) ಅಧಿಷ್ಠಾನ: ಇಲ್ಲಿ ಅಧಿಷ್ಠಾನ ಎಂದರೆ ನೆಲೆ. ನಮ್ಮ ದೇಹವೇ ನಮ್ಮ ಅಧಿಷ್ಠಾನ. ಈ ಸಾಧನಾ ಶರೀರವಿಲ್ಲದೆ\nಯಾವ ಕ್ರಿಯೆಯೂ ನಡೆಯುವುದಿಲ್ಲ. ನಿನಗೆ ದೊರೆತಿರುವ ಸಾಧನಾ ಶರೀರ ಆ ಭಗವಂತನ ಪ್ರಸಾದ.\n\n(೨) ಕರ್ತಾ: ಶರೀರದಲ್ಲಿ ಕೂತು ನಮ್ಮ ಕ್ರಿಯೆಗಳನ್ನು ನಿಯಂತ್ರಿಸುವ ಭಗವಂತ ಕರ್ತಾ. ಆತ ಸ್ವತಂತ್ರ.\nಆತನಿಗೆ ಅಧೀನವಾಗಿರುವ ಜೀವ ಸ್ವತಂತ್ರನಲ್ಲ. ಆದರೆ ಜೀವನಿಗೆ ಇಚ್ಛಾಪೂರ್ವಕ ಕೃತಿ ಇದೆ.\n\n(೩) ಕರಣಗಳು: ನಮ್ಮ ಇಂದ್ರಿಯಗಳು. ನಮ್ಮ ಇಂದ್ರಿಯಗಳನ್ನು ದೇವತೆಗಳು ನಿಯಂತ್ರಿಸುತ್ತಾರೆ.\nಇಂದ್ರಿಯಗಳ ಒಡೆಯ ಭಗವಂತ(ಹೃಷೀಕೇಶ). ಇಂದ್ರಿಯಗಳು ನಮಗೆ ಭಗವಂತನ ಮಹಾ ಪ್ರಸಾದ.\n\n(೪) ವಿವಿಧ ಪೂರಕ ಸಾಧನಗಳು: ಒಂದು ಕ್ರಿಯೆ ಆಗಬೇಕಾದರೆ ಅದಕ್ಕೆ ಪೂರಕವಾದ ಅನೇಕ ಪೂರಕ\nಸಾಧನಗಳು ಅಗತ್ಯ.\n\n(೫) ದೈವಂ: ನಮ್ಮ ಪ್ರತಿಯೊಂದು ಕ್ರಿಯೆ ಭಗವಂತನ ಸಂಕಲ್ಪವನ್ನು ಅವಲಂಭಿಸಿದೆ. ಇದನ್ನು ಅದೃಷ್ಟ,\nಹಣೆಬರಹ ಎಂದೂ ಕರೆಯಬಹುದು.\n\nಈ ಮೇಲಿನ ವಿಷಯವನ್ನು ಉದಾಹರಣೆಯೊಂದಿಗೆ ನೋಡುವುದಾದರೆ- ಒಬ್ಬ ಅತ್ಯುತ್ತಮ ಮಾತುಗಾರ. ಆತ\nಅಷ್ಟೊಂದು ಸ್ವಾರಸ್ಯವಾಗಿ, ವಿಷಯಗರ್ಭಿತವಾಗಿ ಮಾತನಾಡುತ್ತಾನೆ. ಆತ ಹೀಗೆ ಮಾತನಾಡಬೇಕಾದರೆ ಆತ\nಮೂಗನಾಗಿರಬಾರದು, ಬಾಯಿ ಇದ್ದರೆ ಸಾಲದು-ಬಾಯಿಯಲ್ಲಿ ಶಬ್ದ ಬರಬೇಕು. ಕೇವಲ ಶಬ್ದವಲ್ಲ-ಯಾವ\nಮಾತನಾಡಬೇಕೋ ಅದಕ್ಕನುಗುಣವಾದ ಶಬ್ದ ಬರಬೇಕು. ಆ ಶಬ್ದ ಬರಬೇಕಾದರೆ ಮಾತಿಗೆ ಒಂದು ಭಾವ\nಬೇಕು. ಭಾವ ಅನ್ನುವುದು ಮನಸ್ಸಿನಲ್ಲಿ ಹೊಳೆಯಬೇಕು, ಹೊಳೆದ ಭಾವಕ್ಕೆ ತಕ್ಕಂತೆ ಶಬ್ದ ಬರಬೇಕು, ಆ ಶಬ್ದ\nಬಾಯಿಯಲ್ಲಿ ಸ್ಫುಟವಾಗಿ ಹೊರ ಹೊಮ ಬೇಕು. ಭಾವನೆಯಿಂದ ಶಬ್ದದ ಹುಟ್ಟಿಗೆ ಆಕಾಶ-ಗಾಳಿ ಮಾಧ್ಯಮ. ಈ\nಎಲ್ಲಾ ಕ್ರಿಯೆ ಸುಸೂತ್ರವಾಗಿ ನಡೆದರೆ ಮಾತ್ರ ಆತ ಚೆನ್ನಾಗಿ ಮಾತನಾಡಬಲ್ಲ. ಮನಸ್ಸಿನಲ್ಲಿ ಭಾವ ಮತ್ತು\nಶಬ್ದವನ್ನು ಹೊಳೆಸುವವನು ಯಾರು? ಒಂದು ವೇಳೆ ಹೇಳಬೇಕು ಅನ್ನುವ ವಿಷಯಕ್ಕೆ ಅನುಗುಣವಾದ ಶಬ್ದ\nಹೊಳೆಯದೇ ಇದ್ದರೆ? ನಮ್ಮ ಮೆದುಳಿನಲ್ಲಿ ಯಾವುದೋ ಒಂದು ಗುಂಡಿ ಆ ಕ್ಷಣದಲ್ಲಿ ಕೆಲಸ ಮಾಡದೆ ಇದ್ದರೆ?\nಹುಟ್ಟುವಾಗಲೇ ಮೂಗನಾಗಿ ಹುಟ್ಟಿದ್ದರೆ? ಜ್ಞಾನ ಪರಂಪರೆಯೇ ಇಲ್ಲದ ಮನೆತನದಲ್ಲಿ ಹುಟ್ಟಿದ್ದರೆ? ಇಲ್ಲಿ ನಮ್ಮ\nಕೈವಾಡ ಏನಿದೆ? ಇದು ತಿಳಿದಾಗ 'ನಾನು ಮಾಡಿದೆ' ಎನ್ನುವ ಅಹಂಕಾರ ಬಾರದು. ಈ ಅರಿವಿದ್ದಾಗ\nಎಲ್ಲರೊಡನೆ ಎಲ್ಲರಂತೆ ಇದ್ದು ಅಂಟಿಸಿಕೊಳ್ಳದೇ ಇರಲು ಸಾಧ್ಯ.\n",
  "18.15": "ಶರೀರ ವಾಕ್‌ ಮನೋಭಿಃ ಯಶ್‌ ಕರ್ಮ ಪ್ರಾರಭತೇ ನರಃ |\nನ್ಯಾಯ್ಯಂ ವಾ ವಿಪರೀತಂ ವಾ ಪಂಚ ಏತೇ ತಸ್ಯ ಹೇತವಃ - ಮೈ-ಮಾತು-ಮನಗಳಿಂದ ಮನುಷ್ಯ ಯಾವ\nಕೆಲಸ ಕೈಗೊಂಡರೂ -ಅದು ಒಪ್ಪಿರಲಿ, ತಪ್ಪಿರಲಿ-ಇವು ಐದು ಅದಕ್ಕೆ ಕಾರಣಗಳು.\n\nಮೈ-ಮಾತು-ಮನಗಳಿಂದ ನಾವು ಯಾವ ಕ್ರಿಯೆ ಮಾಡಿದರೂ ಅದರ ಹಿಂದೆ ಮೇಲೆ ಹೇಳಿದ ಐದು\nಕಾರಣಗಳಿರುತ್ತವೆ. ಆ ಕ್ರಿಯೆ ಒಳ್ಳೆಯದಿರಬಹುದು ಅಥವಾ ಕೆಟ್ಟದ್ದಿರಬಹುದು. ಕ್ರಿಯೆ ಮಾತ್ರ ಈ ಐದು\nಕಾರಣಗಳಿಂದಲೇ ನಡೆಯುವುದು.\n",
  "18.16": "ತತ್ರ ಏವಂ ಸತಿ ಕರ್ತಾರಮ್‌ ಆತ್ಮಾನಂ ಕೇವಲಂ ತು ಯಃ।\n\nಪಶ್ಯತಿ ಅಕೃತ ಬುದ್ಧಿತ್ವಾತ್‌ ನ ಸಃ ಪಶ್ಯತಿ ದುರ್ಮತಿಃ -ಅದು ಹೀಗಿರುವಾಗ, ಏನೂ ಮಾಡದ ತನ್ನನ್ನು\n\"ಮಾಡುವವನು' ಎಂದು [ತಾನೊಬ್ಬನೇ ಎಲ್ಲಾ ಮಾಡಿದವನು ಎಂದು] ತಿಳಿದವನು ಬುದ್ಧಿಗೇಡಿ. ಆ\nತಿಳಿಗೇಡಿಗಳಿಗೆ ಏನೂ ತಿಳಿದಿಲ್ಲ.\n\nಈ ರೀತಿ ಐದು ಕಾರಣಗಳು ನಮ್ಮ ಕ್ರಿಯೆಯಲ್ಲಿ ಪಾತ್ರಧಾರಿಗಳಾಗಿರುವಾಗ, ಅದನ್ನು ಅರಿಯದೇ, “ನಾನು\nಮಾಡಿದೆ” ಎಂದು ಅಹಂಕಾರ ಪಟ್ಟುಕೊಳ್ಳುವುದು ಅರ್ಥಶೂನ್ಯ. ಈ ರೀತಿ ತಿಳಿದುಕೊಳ್ಳುವವರು ಬುದ್ಧಿಗೇಡಿಗಳು.\nಇಂತಹ ಮತಿಗೇಡಿಗಳು ಏನನ್ನೂ ತಿಳಿದಿಲ್ಲ.\n",
  "18.17": "ಯಸ್ಯ ನ ಅಹಂಕೃತಃ ಭಾವಃ ಬುದ್ಧಿಃ ಯಸ್ಯ ನ ಲಿಪ್ಯತೇ ।\n\nಹತ್ವಾ ಅಪಿ ಸ ಇಮಾನ್‌ ಲೋಕಾನ್‌ ನ ಹಂತಿ. ನ ನಿಬಧ್ಯತೇ - ನಾನು ಮಾಡಿದೆ ಎಂಬ ಹಮ್ಮಿರದವನು,\nಬಗೆಯಲ್ಲಿ ಫಲದ ನಂಟಿರದವನು, ಈ ಮಂದಿಯನ್ನೆಲ್ಲಾ ಕೊಂದರೂ ಯಾರನ್ನೂ ಕೊಲ್ಲುವುದಿಲ್ಲ. ಕರ್ಮದ ಸೆರೆ\nಅವನನ್ನು ಸೋಕದು.\n\nಕರ್ಮಫಲದ ತ್ಯಾಗ ಮಾಡಿದವ ಯಾವ ಕರ್ಮ ಮಾಡಿದರೂ ಅದು ಅವನಿಗೆ ಬಾಧಕವಾಗುವುದಿಲ್ಲ. ನಾವು\n“ನನ್ನಿಂದಾಯಿತು' ಎಂದು ಅಂಟಿಸಿಕೊಳ್ಳದೆ, ಯಾವುದೇ ಫಲಾಪೇಕ್ಷೆ ಇಲ್ಲದೆ, ಕರ್ಮ ಮಾಡಿದಾಗ-ಆ ಕರ್ಮದ\nಫಲ ಎಂದೂ ನಮ್ಮನ್ನು ಬಾಧಿಸುವುದಿಲ್ಲ. ನಾವು ಮಹಾಭಾರತ ಯುದ್ಧದ ಸನ್ನಿವೇಶವನ್ನು ನೋಡಿದರೆ-\nಪಾಂಡವರಿಗೆ ಯುದ್ಧ ಅನಿವಾರ್ಯವಾಗಿ ಒದಗಿಬಂದಿರುವುದು. ಅವರು ಎಂದೂ ಯುದ್ಧವಾಗಬೇಕು ಎಂದು\nಬಯಸಿಲ್ಲ; ಯುದ್ಧದಲ್ಲಿ ಗೆದ್ದು ಅಧಿಕಾರ ಪಡೆಯಬೇಕು. ಎಂತಲೂ ಯೋಚಿಸಿಲ್ಲ. ಆದರೆ ಅವರಿಗೆ\nಅನಿವಾರ್ಯವಾಗಿ ಯುದ್ಧಮಾಡುವ ಸನ್ನಿವೇಶ ಎದುರಿಗೆ ಬಂದು ನಿಂತಿತು. ಅವರು ಅದನ್ನು 'ಇದು ದೈವೇಚ್ಛೆ'\nಎಂದು ಯುದ್ಧದ ಪರಿಣಾಮದ ಬಗ್ಗೆ ಯೋಚಿಸದೆ ಭಗವದರ್ಪಣಾ ಭಾವದಿಂದ ಮಾಡಿದರು. ಈ ರೀತಿ ಒದಗಿ\n\nಬಂದ ಯುದ್ಧದಲ್ಲಿ ಅವರು ಅನೇಕಾನೇಕ ಯೋಧರನ್ನು ಕೊಲ್ಲಬೇಕಾಯಿತು. ಆದರೆ ಅವರು ತಮ್ಮ ಕರ್ತವ್ಯ\nಕರ್ಮವನ್ನು ಫಲಾಪೇಕ್ಷೆ, ಅಹಂಕಾರವಿಲ್ಲದೆ ಮಾಡಿದರು. ಈ ರೀತಿ \"ನಿರ್ಲಿಪ್ತ ಮನಸ್ಸಿನಿಂದ ಯುದ್ಧ ಭೂಮಿಯಲ್ಲಿ\nಅನೇಕ ಜನರನ್ನು ಕೊಲ್ಲುವ ಪ್ರಸಂಗ ಬಂದರೂ ಕೂಡಾ-ಆ ಕೊಂದ ಪಾಪ ಕೊಂದವನನ್ನು ಸೋಕುವುದಿಲ್ಲ”\nಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಆದರೆ ಇಲ್ಲಿ ಬಹಳ ಮುಖ್ಯ ವಿಚಾರ ಎಂದರೆ-ಮಾನಸಿಕವಾಗಿ ಒಂದು ಕ್ಷಣವೂ ನಮಗೆ\nಭಗವಂತನ ಮೇಲೆ ಅಪನಂಬಿಕೆ ಬರಕೂಡಾದು; ಸಂಪೂರ್ಣ ಅರ್ಪಣಾ ಭಾವದಲ್ಲಿ,\nನಿಶ್ಚಿತಾಭಿಪ್ರಾಯದಲ್ಲಿ ನಮ್ಮ ಪಾಲಿಗೆ ಒದಗಿ ಬಂದಿರುವ ಕರ್ಮವನ್ನು ಫಲಾಪೇಕ್ಷೆ ಇಲ್ಲದೆ\nಮಾಡಬೇಕು. ಭಗವಂತನ ಕೈಯಲ್ಲಿ ನಾನು ಒಂದು ಸಾಧನ ಎನ್ನುವ ಎಚ್ಚರದಿಂದ ಎಲ್ಲವನ್ನು\nಭಗವಂತನ ಚರಣಗಳಿಗೆ ಅರ್ಪಿಸಿ ಕರ್ಮವನ್ನು ಮಾಡಿದಾಗ ಕರ್ಮದ ಸೆರೆ ನಮ್ಮನ್ನು ಸೋಕುವುದಿಲ್ಲ. ಜೀವನಿಗೆ\nಕರ್ಮದ ಫಲ ತಟ್ಟುವುದೇ ಅವನು 'ನಾನು ಮಾಡಿದೆ' ಎಂದು ತಿಳಿದುಕೊಳ್ಳುವುದರಿಂದ.\n\nಇಲ್ಲಿ ನಮಗೆ ಒಂದು ಪ್ರಶ್ನೆ ಮೂಡಬಹುದು. ಜೀವನಿಗೆ ಸ್ವತಂತ್ರ ಕರ್ತೃತ್ವ ಇಲ್ಲ, ಕರ್ಮ ಭಗವದಿಚ್ಛೆಯಂತೆ\nನಡೆಯುತ್ತದೆ. ಹೀಗಿರುವಾಗ ಜೀವನಿಗೆ ವಿಧಿನಿಷೇಧ ಏಕೆ? ಶಾಸ್ತ್ರ ಏಕೆ ಅದನ್ನು ಮಾಡು, ಇದನ್ನು ಮಾಡಬೇಡ\nಎಂದು ಹೇಳುತ್ತದೆ? ಈ ಪ್ರಶ್ನೆಗೆ ಕೃಷ್ಣ ಮುಂದಿನ ಶ್ಲೋಕದಲ್ಲಿ ಉತ್ತರಿಸಿದ್ದಾನೆ.\n",
  "18.18": "ಜ್ಞಾನಂ ಜ್ಞೇಯಂ ಪರಿಜ್ಞಾತಾ ತ್ರಿವಿಧಾ ಕರ್ಮ ಚೋದನಾ |\n\nಕರಣಂ ಕರ್ಮ ಕರ್ತಾ ಇತಿ ತ್ರಿವಿಧ; ಕರ್ಮಸಂಗ್ರಹಃ -ಕರ್ಮ ವಿಧಿಯ ಉದ್ದೇಶ ಮೂರು: ಮಾಡಬೇಕೆಂಬ\nಅರಿವು, ಅದಕ್ಕಾಗಿ ಅರಿಯಬೇಕಾದ ಕರ್ಮ,ಕರ್ಮಫಲ ಮತ್ತು ಅರಿತು ಮಾಡುವವನು. [ಕರ್ಮಕ್ಕೆ ಕಾರಣವಾದ\nಭಗವಂತನ ಪ್ರೇರಣೆ ಅವನ ಸ್ವರೂಪವೇ. ಆದ್ದರಿಂದ ಮುಮ್ಮುಖವಾದ ಅದು ಅರಿವಿನ ರೂಪ, ಎಲ್ಲರೂ\nಅರಿಯಬೇಕಾದಂತಹದ್ದು ಮತ್ತು ಎಲ್ಲವನ್ನೂ ಬಲ್ಲುದು] ಕರ್ಮದ ಕಾರಣವೂ ಅಡಕವಾಗಿ ಮೂರು ತೆರ:\nಉಪಕರಣ, ಮಾಡುವಿಕೆ ಮತ್ತು ಮಾಡುವವನು.\n\nವಿಧಿನಿಷೇಧ ಇರುವುದು ನಮ್ಮ ಜ್ಞಾನಕ್ಕಾಗಿ. \"ಭಗವಂತನನ್ನು 'ನಾನು' ತಿಳಿದುಕೊಳ್ಳಬೇಕು” ಎನ್ನುವುದಕ್ಕಾಗಿ\nಕರ್ಮದ ವಿಧಿನಿಷೇಧ. ಕರ್ಮ ಮಾಡುವುದು ಕರ್ಮಕ್ಕಾಗಿ ಅಲ್ಲ-ಜ್ಞಾನಕ್ಕಾಗಿ. ಕರ್ಮದ ವಿಧಾನದ ಹಿಂದಿರುವುದು\nಕಾರುಣ್ಯ. ಜ್ಞಾನವಿಲ್ಲದ ಲೋಕಕ್ಕೆ ಭಗವಂತನ ಜ್ಞಾನ-ಆ ಜ್ಞಾನಕ್ಕೆ ಪೂರಕವಾಗಿ ಕರ್ಮ. ಕರ್ಮದ ಹಿಂದಿರುವ\nಪ್ರೇರಣೆ ಮೂರು: ಜ್ಞಾನ, ಜ್ಞೇಯ ಮತ್ತು ಜ್ಞಾತಾ. ಒಂದು ಕ್ರಿಯೆಯನ್ನು ಮಾಡಬೇಕು ಅನ್ನುವ ಅರಿವು; ಆ\nಕ್ರಿಯೆಯನ್ನು ಮಾಡಲು ಅರಿಯಬೇಕಾದ ಕರ್ಮ; ಮತ್ತು ಕರ್ಮವನ್ನು ಅರಿತು ಕರ್ಮವನ್ನು ಮಾಡುವವನು.\nಭಗವಂತನನ್ನು ತಿಳಿದುಕೊಳ್ಳಬೇಕು ಎನ್ನುವುದು ಕರ್ಮದ ಹಿಂದಿನ ಮೂಲಪ್ರೇರಣೆ. ಕರ್ಮ ಮಾಡುವುದು ನಮ್ಮ\nತಿಳಿಗೇಡಿತನವನ್ನು.. ಕಳಚಿಕೊಂಡು ಜ್ಞಾನವನ್ನು ಪಡೆಯುವುದಕ್ಕೋಸ್ಕರ; ನಮ್ಮ ಅರಿವನ್ನು\n\nಬೆಳೆಸುವುದಕ್ಕೋಸ್ಕರ; ಆ ಅರಿವು ಭಗವನ್ಮುಖವಾಗುವುದಕ್ಕೋಸ್ಕರ. ನಾವು\nಅರಿವುಳ್ಳವರಾಗುವುದಕ್ಕೋಸ್ಕರವೇ ಕರ್ಮವಿಧಿನಿಷೇಧ ಶಾಸ್ತ್ರಕಾರರಿಂದ ಬಂತು.\n\nಜೀವನಿಗೆ ಕರ್ಮ ಮಾಡಬೇಕು ಎನ್ನುವ ಪ್ರೇರಣೆ ಮಾಡುವವ-ಭಗವಂತ. ಅದಕ್ಕನುಗುಣವಾಗಿಯೇ ಜೀವ ಕರ್ಮ\nಮಾಡುತ್ತಾನೆ. ಯಾವ ಜೀವ ಏನು ಆಗಬೇಕು ಎನ್ನುವುದು ಆ ಜೀವದ ಸ್ವರೂಪಕ್ಕೆ ಸಂಬಂಧಪಟ್ಟ ವಿಚಾರ.\nಆದರೆ ಸ್ವಯಂ ಜೀವನಿಗೆ ಅದನ್ನು ಅಭಿವ್ಯಕ್ತಗೊಳಿಸುವ ಶಕ್ತಿ ಇಲ್ಲ. ಭಗವಂತ ಆ ಜೀವ ಸ್ವರೂಪದ\nಯೋಗ್ಯತೆಗನುಗುಣವಾಗಿ ಆತನಲ್ಲಿ ಪ್ರೇರಣೆ ಮಾಡುತ್ತಾನೆ. ಭಗವಂತನ ಪ್ರೇರಣೆಯಿಂದ ಜೀವಯೋಗ್ಯತೆ\nವ್ಯಕ್ತವಾಗುತ್ತದೆ ಮತ್ತು ಅದಕ್ಕನುಗುಣವಾಗಿ ಜೀವ ಕರ್ಮದಲ್ಲಿ ತೊಡಗುತ್ತಾನೆ. ಇಲ್ಲಿ ಎಲ್ಲವೂ ಮೂಲತಃ\nಭಗವದ್‌ ಸ್ವರೂಪ. ಭಗವಂತನ ಜ್ಞಾನ-ಭಗವದ್‌ ಸ್ವರೂಪ, ಭಗವಂತನ ಕ್ರಿಯೆ-ಭಗವದ್‌ ಸ್ವರೂಪ, ಭಗವಂತನ\nಪ್ರೇರಣೆ-ಭಗವದ್‌ ಸ್ವರೂಪ. ಭಗವಂತನ ಸ್ವರೂಪ ನೇರ ನಮ್ಮ ಮೇಲೆ ಕೆಲಸ ಮಾಡುತ್ತಿರುತ್ತದೆ. ಅವನೇ\nಜ್ಞಾನ, ಅವನೇ ಜ್ಞೇಯ, ಅವನೇ ಜ್ಞಾತೃ. ಆದ್ದರಿಂದ ಅವನ ಪ್ರೇರಣೆ-ಜ್ಞಾನಸ್ವರೂಪ; ಅವನ ಪ್ರೇರಣೆ-\nಜ್ಞಾತೃಸ್ವರೂಪ; ಅವನ ಪ್ರೇರಣೆ-ಜ್ಞೇಯ. ಹೀಗೆ ಜ್ಞಾನಸ್ವರೂಪನಾದ ಭಗವಂತನ ಪ್ರೇರಣೆಯಿಂದ ಜೀವ ಕರ್ಮ\nಮಾಡುತ್ತಾನೆ ಮತ್ತು ಎಲ್ಲವೂ ಅವನ ಅಧೀನವಾಗಿ ನಡೆಯುತ್ತದೆ.\n\nಒಟ್ಟಿನಲ್ಲಿ ಕರ್ಮದ ಕಾರಣಗಳನ್ನು ಅಡಕವಾಗಿ ಹೇಳಬೇಕೆಂದರೆ ಅವು ಮೂರು ವಿಧ: ದೇಹ ಇಂದ್ರಿಯಾದಿ\nಉಪಕರಣಗಳು, ಮಾಡುವಿಕೆ(ಕರ್ಮ) ಮತ್ತು ಕರ್ತಾ(ಜೀವ,ಭಗವಂತ ಮತ್ತು ಅದೃಷ್ಟ).\n\nಗುಣತ್ರಯಗಳ ಬಗ್ಗೆ ಹಿಂದೆ ಸಾಕಷ್ಟು ವಿವರಗಳನ್ನು ಕೊಟ್ಟಿದ್ದ ಕೃಷ್ಣ, ಇಲ್ಲಿ ಜೀವನಕ್ಕೆ ಬಹಳ ಮುಖ್ಯವಾದ\nತ್ರೈಗುಣ್ಯ ವಿದ್ಯೆಯನ್ನು ವಿವರಿಸಿದ್ದಾನೆ.\n",
  "18.19": "ಜ್ಞಾನಂ ಕರ್ಮ ಚ ಕರ್ತಾ ಚ ತ್ರಿಧಾ ಏವ ಗುಣಭೇದತಃ |\n\nಪ್ರೋಚ್ಯತೇ ಗುಣಸಂಖ್ಯಾನೇ ಯಥಾವತ್‌ ಶೃಣು ತಾನಿ ಅಪಿ - ಅರಿವು, ಕಾಯಕ ಮತ್ತು ಮಾಡುವಾತ ಕೂಡಾ\nಗುಣಗಳ ಭೇದದಿಂದ ಮೂರು ತೆರ ಎಂದು ಗುಣಗಳ ಎಣಿಕೆಯ ಪ್ರಕರಣದಲ್ಲಿ [ವೈದಿಕ ಸಾಂಖ್ಯಾ ಶಾಸ್ತ್ರದಲ್ಲಿ]\nಹೇಳಲಾಗಿದೆ. ಅವುಗಳನ್ನು ಹಾಗೆಯೇ ಆಲಿಸು.\n\nಪ್ರತಿಯೊಬ್ಬನ ಬದುಕಿನಲ್ಲಿರುವ ಮೂರು ಪ್ರಮುಖ ಘಟಕಗಳೆಂದರೆ ಅರಿವು(ಜ್ಞಾನ), ಕಾಯಕ(ಕರ್ಮ) ಮತ್ತು\nಕರ್ತಾ(ಮಾಡುವಾತ). ಏನನ್ನೇ ಮಾಡುವುದಾದರೂ ಕೂಡಾ ಒಂದು ತಿಳುವಳಿಕೆಯಿಂದ ಮಾಡುತ್ತೇವೆ-ಅದು\nಜ್ಞಾನ; ಆ ತಿಳುವಳಿಕೆಯಿಂದ “ಮಾಡುವುದು'-ಕರ್ಮ; ಜ್ಞಾನ ಮತ್ತು ಕರ್ಮಗಳಿಗೆ ಆಶ್ರಿತನಾಗಿರತಕ್ಕಂತವ-\nಕರ್ತಾ. ಈ ಮೂರೂ ಕೂಡಾ ಗುಣತ್ರಯ ವಿಭಾಗಕ್ಕೆ ಒಳಪಟ್ಟು ಪ್ರತಿಯೊಂದೂ ಮತ್ತೆ ಮೂರು ವಿಧವಾಗಿದೆ.\nಶಾಸ್ತ್ರದಲ್ಲಿ ಎಲ್ಲಿ ಗುಣಗಳ ಪರಿಗಣನೆ ಆಗುತ್ತದೋ ಅಲ್ಲಿ ಈ ವಿಷಯ ಹೇಳಿದ್ದಾರೆ ಮತ್ತು ಭಗವಂತ\nಕಪಿಲವಾಸುದೇವನಾಗಿ ಜಗತ್ತಿಗೆ ಕೊಟ್ಟ 'ಪರಮಸಾಂಖ್ಯದಲ್ಲಿ' ಇದನ್ನು ಹೇಳಲಾಗಿದೆ. ಇದು ಕಪಿಲ\n\nವಾಸುದೇವನಿಂದ ಮೊಟ್ಟ ಮೊದಲು ಹೇಳಲ್ಬ ಟ್ಟ, ಪುರಾತನ ಕಾಲದಿಂದಲೂ ಇದ್ದ, ಜಗತ್ತಿಗೆ ಹೇಳಬೇಕಾದ\nವಿಷಯಗಳಲ್ಲೇ ಅತ್ಯಂತ ಪ್ರಕೃಷ್ಣವಾದ ವಿಷಯ. ತೈಗುಣ್ಯವಿಲ್ಲದೆ ಜೀವನವೇ ಇಲ್ಲ. ನಮ್ಮ ಬದುಕಿನ ಎಲ್ಲಾ\nಮುಖದಲ್ಲೂ ವ್ಯಾಪಿಸಿರುವ ಈ ತ್ರೈಗುಣ್ಯವನ್ನು ನಾವು ಅರ್ಥಮಾಡಿಕೊಳ್ಳದಿದ್ದರೆ ನಮ್ಮ ಬದುಕನ್ನು ತಿದ್ದಿಕೊಳ್ಳಲು\nಸಾಧ್ಯವಿಲ್ಲ ಮತ್ತು ತ್ರಿಗುಣಾತೀತ ಭಗವಂತನ ಕಡೆಗೆ ಸಾಗಲು ಸಾಧ್ಯವಿಲ್ಲ. “ಅತ್ಯಂತ ಪುರಾತನವಾದ ಈ\nಮೂಲಭೂತ ಸತ್ಯವನ್ನು ನಾನು ನಿನಗೆ ತದ್ವತ್ತಾಗಿ ಹೇಳುತ್ತೇನೆ -ಅದನ್ನು ಗಮನವಿಟ್ಟು ಆಲಿಸು” ಎಂದು ಕೃಷ್ಣ\nಅರ್ಜುನನಲ್ಲಿ ಹೇಳುತ್ತಾನೆ.\n",
  "18.20": "ಸರ್ವಭೂತೇಷು ಯೇನ ಏಕಂ ಭಾವಂ ಅವ್ಯಯಮ್‌ ಈಕ್ಷತೇ ।\nಅವಿಭಕ್ತಂ ವಿಭಕ್ತೇಷು ತತ್‌ ಜ್ಞಾನಂ ವಿದ್ಧಿ ಸಾತ್ತ್ವಿಕಮ್‌ - ಎಲ್ಲಾ ಜೀವಿಗಳಲ್ಲಿ ಬದಲಾಗದ ಒಂದು ಪರತತ್ವವನ್ನು ಸ\nಬಗೆಬಗೆಯ ವಸ್ತುಗಳಲ್ಲಿ ಒಂದೇ ಬಗೆಯ ಭಗವಂತನನ್ನು ಕಾಣುವ ತಿಳಿವು ಸಾತ್ವಿಕ ಎಂದು ತಿಳಿ.\n\nಬೃಹದಾರಣ್ಯಕ ಉಪನಿಷತ್ತಿನಲ್ಲಿ(೪-೫-೧೧)ಹೇಳುವಂತೆ: “ಅಸ್ಯ ಮಹತೋ ಭೂತಸ್ಯ ನಿಶ್ವಸಿತಮ್‌”- \"ಅಂದರೆ\nಇಡೀ ಪ್ರಪಂಚ ಆ ಮಹಾಭೂತದ ಉಸಿರಿನ ಉದ್ಗಾರ'. ವಿಷ್ಣು ಸಹಸ್ರನಾಮದಲ್ಲಿ ಹೇಳುತ್ತಾರೆ: “ಏಕೋ\nವಿಷ್ಣುರ್ಮಹದ್ಭೂತಂ ಪೃಥಗ್ಳೂತಾನ್ಯನೇಕಶಃ\" ಎಂದು. ಅಂದರೆ ಒಬ್ಬನೇ ಒಬ್ಬ ವಿಷ್ಣು ಹಿರಿಯ\nಚೇತನ(ಮಹಾಭೂತ); ಅಲ್ಪ ಚೇತನಗಳು(ಭೂತಗಳು) ಹಲವಾರು ಎಂದು. ಗೀತೆಯ ಈ ಶ್ಲೋಕದಲ್ಲಿ ಕೃಷ್ಣ\nಸಾತ್ವಿಕ ಅರಿವಿನ ಬಗ್ಗೆ ಹೇಳುತ್ತಾ ಹೇಳುತ್ತಾನೆ: “ಪರಸ್ಪರ ಭಿನ್ನವಾದ, ಒಂದರಂತೆ ಇನ್ನೊಂದಿಲ್ಲದ,\nವಿಲಕ್ಷಣವಾದ ಜೀವಪ್ರಪಂಚದಲ್ಲಿ(ಸರ್ವಭೂತೇಷು)- ಯಾವ ಭೇದವೂ ಇಲ್ಲದೆ, ಪೂರ್ಣ ಗುಣಕ್ರಿಯೆಯಲ್ಲಿ\nಅಖಂಡ ಸತ್ಯವಾಗಿರುವ ಒಂದು ತತ್ವ ನೆಲೆಸಿದೆ. ಅನಂತದಲ್ಲಿ ಏಕವಾಗಿರುವ, ತ್ರೈಗುಣ್ಯವರ್ಜಿತ\nಭಗವಂತನೆಂಬ ಈ ತತ್ವ ಯಾವ ಅರಿವಿಗೆ ಗೋಚರವಾಗುತ್ತದೋ ಆ ಅರಿವು ಸಾತ್ವಿಕ” ಎಂದು.",
  "18.21": "ಪೃಥಕ್‌ ತ್ವೇನ ತು ಯತ್‌ ಜ್ಞಾನಂ ನಾನಾಭಾವಾನ್‌ ಪ್ರಥಗ್‌ ವಿಧಾನ್‌ |\n\nವೇತ್ತಿ ಸರ್ವೇಷು ಭೂತೇಷು ತತ್‌ ಜ್ಞಾನಂ ವಿದ್ಧಿ ರಾಜಸಮ್‌ - ಭಗವಂತನ ಶಕ್ತಿಯಲ್ಲಿ ಅಂತರವನ್ನು\nಕಾಣುವುದು, ಎಲ್ಲಾ ಜೀವಿಗಳಲ್ಲಿ ಬಗೆಬಗೆಯ ದೈವೀಶಕ್ತಿಗಳು ಬೇರೆಬೇರೆಯಾಗಿ ಕೆಲಸ ಮಾಡುತ್ತಿವೆ ಎಂದು\nತಿಳಿಯುವುದು[ಎಲ್ಲಾ ಜೀವಿಗಳಲ್ಲಿರುವ ಭೇದವನ್ನು ಮಾತ್ರ ಗುರುತಿಸುವ, ಒಂದರಂತೆ ಒಂದಿಲ್ಲ ಎಂದರಿಯುವ,\nಆದರೆ ಭಗವತ್‌ ಪ್ರಜ್ಞೆಯಿರದ ಕೇವಲ ಭೌತಿಕ ನಿಜದರಿವು] ರಾಜಸ ಎಂದು ತಿಳಿ.\n\nಏಕಭಕ್ತಿ ಇಲ್ಲದೆ ಅನೇಕ ದೇವತಾವಾದದಲ್ಲಿ ನಂಬಿಕೆ-ರಾಜಸ ಅರಿವು. ಇವರಿಗೆ ಅಖಂಡವಾದ ಪರತತ್ವದ\nಎಚ್ಚರವಿರುವುದಿಲ್ಲ. ಇವರು ಬೇರೆ ಬೇರೆ ಸಂದರ್ಭದಲ್ಲಿ ಬೇರೆ ಬೇರೆ ದೇವತೆಗಳನ್ನು ಪೂಜೆ ಮಾಡುತ್ತಾರೆ.\nಇಂದಿನ ಜ್ಯೋತಿಷ್ಯ ಕೂಡಾ ಜನರನ್ನು ಈ ತಪ್ಪು ದಾರಿಯಲ್ಲಿ ಹೋಗುವಂತೆ ಪ್ರೇರಣೆ ಮಾಡುತ್ತಿದೆ.\nಅಖಂಡವಾದ ಭಗವಂತನ ಐಎಚ್ಚರವಿಲ್ಲದೆ ಒಂದೊಂದು ಗ್ರಹಚಾರಕ್ಕೆ ಒಂದೊಂದು ದೇವತೆಯಪೂಜೆ\nಮಾಡುವುದು ರಾಜಸ ಅರಿವು. ಯಾವ ಪೂಜೆಯೇ ಇರಲಿ ಅದನ್ನು ಸರ್ವನಿಯಾಮಕ ಭಗವಂತನ ಎಚ್ಚರದಿಂದ\nಮಾಡಿದರೆ ಆ ಪೂಜೆ ಸಾತ್ವಿಕವಾಗುತ್ತದೆ. ಅದನ್ನು ಬಿಟ್ಟು ನಾನಾ ದೇವತೆಗಳನ್ನು ಬೇರೆಯಾಗಿ ಪೂಜಿಸಿದಾಗ\nಅದೇ ಪೂಜೆ ರಾಜಸವಾಗುತ್ತದೆ.\n",
  "18.22": "ಯತ್‌ ತು ಕೃತ್ಸ _ವತ್‌ ಏಕಸ್ಮಿನ್‌ ಕಾರ್ಯೇ ಸಕ್ತಮ್‌ ಅಹೈತುಕಮ್‌ ।\n\nಅತತ್ತ್ವ ಅರ್ಥವತ್‌ ಅಲ್ಬಂ ಚ ತತ್‌ ತಾಮಸಮ್‌ ಉದಾಹೃತಮ್‌ -- ಯಾವುದೋ ಒಂದು ಕ್ಷುದ್ರವಾದ ಕಜ್ಜಕ್ಕೆ\nಅಂಟಿಕೊಂಡು ಅದೇ ಸರ್ವಸ್ವವೆಂದು [ಬದಲಾಗದ ಜೀವವನ್ನೇ ಬದಲಾಗದ ಭಗವಂತನೆಂದು, ಇಡಿಯ ವಿಶ್ವ\nಒಬ್ಬ ಜೀವನ ಕಲ್ಪನಾವಿಲಾಸ ಎಂದು] ನಂಬುವ, ಕಾರಣವಿರದ, ನಿಜವನ್ನು ಗ್ರಹಿಸದ [ವಿಶ್ವ ನಿಜವಲ್ಲ ಎಂದು\nಗ್ರಹಿಸುವ] ಕ್ಷುಲ್ಲಕವಾದ ತಿಳಿವು ತಾಮಸ ಎನಿಸುತ್ತದೆ.\n\nತಾಮಸ ಸ್ವಭಾವಕ್ಕೆ ಅನೇಕ ಮುಖಗಳು. ಕಾಣುವುದು ಅನೇಕ-ಇರುವುದು ಏಕ ಎಂದು ತಿಳಿಯುವುದು;\nಜೀವನಿಗಿಂತ ಬೇರೆಯಾದ ಭಗವಂತನನ್ನು ಒಪ್ಪದಿರುವುದು; ಈ ಪ್ರಪಂಚದಲ್ಲಿ ಯಥಾರ್ಥವಾದ ವಸ್ತುವಿಗೆ\nಅಸ್ತಿತ್ವವೇ ಇಲ್ಲ ಎಂದು ತಿಳಿದುಕೊಳ್ಳುವುದು; ಅಜ್ಞಾನ-ಅದರಿಂದ ವಿಪರೀತಜ್ಞಾನ; ಅರಿವಿಲ್ಲದಿದ್ದರೂ ಕೂಡಾ\nತನ್ನನ್ನು ತಾನು ಮಹಾಜ್ಞಾನಿ ಎಂದು ಭ್ರಮಿಸುವುದು; ಯಾವುದೋ ಒಂದು ವಿಷಯವನ್ನು ತಿಳಿದುಕೊಂಡು\nನಾನು ಎಲ್ಲವನ್ನೂ ತಿಳಿದಿದ್ದೇನೆ ಅಂದುಕೊಳ್ಳುವುದು; ಇತ್ಯಾದಿ ತಾಮಸ ಅರಿವು ಎನಿಸುತ್ತದೆ. ನಾವು ನಮ್ಮ\nಜ್ಞಾನದ ಇತಿ-ಮಿತಿಯನ್ನು ಅರಿತು ಪ್ರತೀ ಕ್ಷಣ ಅದಕ್ಕಿಂತ ಹೆಚ್ಚಿನ ಸತ್ಯವನ್ನು ತಿಳಿಯಲು ನಿರಂತರ ಪ್ರಯತ್ನ\nಮಾಡಬೇಕು-ಇಲ್ಲದಿದ್ದರೆ.. ನಾವು. ತಾಮಸರಾಗುತ್ತೇವೆ. ದ್ವೈತ ಸಿದ್ಧಾಂತ ನಮಗೆ ಸರಿಯಾಗಿ\nಅರ್ಥವಾಗಬೇಕಾದರೆ. ಸಾವು. ಅದ್ವೈತ ಮತ್ತು ವಿಶಿಷ್ಟಾದ್ವೈತವನ್ನು.. ಓದಿರಬೇಕು. ಹಿಂದುತ್ವ\nಅರ್ಥವಾಗಬೇಕಾದರೆ ಮುಸ್ಲಿಂ ಮತ್ತು ಕ್ರೈಸ್ತ ಧರ್ಮ ಏನು ಹೇಳುತ್ತದೆ ಎನ್ನುವ ಅರಿವು ನಮಗಿರಬೇಕು. ಇದನ್ನು\nಬಿಟ್ಟು ನಾನು ನಂಬಿದ್ದೇ ಸತ್ಯ ಉಳಿದದ್ದೆಲ್ಲ ಮಿಥ್ಯ ಎಂದು ಗ್ರಹಿಸುವವನ ಮೂಢ ಅರಿವು ತಾಮಸವೆನಿಸುತ್ತದೆ.\nಸದಾ ಸತ್ಯದ ಹುಡುಕಾಟ, ಜ್ಞಾನದ ದಾಹ- ನಮ್ಮನ್ನು ಸಾತ್ವಿಕತೆಯತ್ತ ಕೊಂಡೊಯ್ಯಬಲ್ಲದು. ಜ್ಞಾನವನ್ನು ತನ್ನ\nಲೌಕಿಕ, ವ್ಯಾವಹಾರಿಕ ಬದುಕಿಗೆ ಸೀಮಿತಗೊಳಿಸಿಕೊಂಡು; ಇನ್ನೊಬ್ಬರಲ್ಲಿರುವ ಸಾತ್ವಿಕ ಜ್ಞಾನವನ್ನು\nಗುರುತಿಸದೆ; ಪರಮಾತ್ಮನ ಪ್ರಜ್ಞೆ ಇಲ್ಲದ ಅನುಷ್ಠಾನದಲ್ಲಿ ಬದುಕುವಂತೆ ಮಾಡುವ ಮೂಢ ಅರಿವು ತಾಮಸ.\n",
  "18.23": "ನಿಯತಮ್‌ ಸಂಗರಹಿತಮ್‌ ಆರಾಗ ದ್ವೇಷತಃ ಕೃತಮ್‌ |\nಅಫಲಪ್ರೇಪ್ಸುನಾ ಕರ್ಮ ಯತ್‌ ತತ್‌ ಸಾತ್ತ್ವಿಕಮ್‌ ಉಚ್ಯತೇ - ಹಚ್ಚಿಕೊಳ್ಳದೆ, ಮೆಚ್ಚು-ಕಿಚ್ಚುಗಳಿಗೊಳಗಾಗದೆ,\nಫಲದ ಹಂಬಲವಿರದೇ ಮಾಡಿದ ವಿಹಿತವಾದ ಕರ್ಮ ಸಾತ್ವಿಕ ಎನಿಸುತ್ತದೆ.\n\nನಮಗೆ ಪ್ರಾಪ್ತವಾಗಿರುವ ವಿಹಿತಕರ್ಮವನ್ನು ಭಗವಂತನ ಪೂಜಾರೂಪವಾಗಿ ಮಾಡಿದಾಗ ಅದು ಸಾತ್ವಿಕ\nಕರ್ಮವಾಗುತ್ತದೆ. ಈ ಕರ್ಮದಲ್ಲಿ ಯಾವುದೇ ರಾಗ-ದ್ವೇಷವಿಲ್ಲ; ಫಲಾಪೇಕ್ಷೆಯಿಲ್ಲ; ಯಾವುದೇ ರೀತಿ\nಅಂಟಿಸಿಕೊಳ್ಳುವಿಕೆಯಿಲ್ಲ.ಶ್ರದ್ಧಾ-ಭಕ್ತಿಯಿಂದ, . ನಿರ್ಲಿಪ್ತತೆಯಿಂದ, ಕರ್ತವ್ಯವನ್ನು ನಿರ್ವಂಚನೆಯಿಂದ\nಭಗವದರ್ಪಣಾಭಾವದಿಂದ ಮಾಡುವ ಕರ್ಮ ಸಾತ್ವಿಕ ಕರ್ಮ.",
  "18.24": "ಯತ್‌ ತು ಕಾಮ ಈಪ್ಸುನಾ ಕರ್ಮ ಸಅಹಂಕಾರೇಣ ವಾ ಪುನಃ ।\nಕ್ರಿಯತೇ ಬಹುಲ ಆಯಾಸಮ್‌ ತತ್‌ ರಾಜಸಮ್‌ ಉದಾಹೃತಮ್‌ -ಫಲದ ಬಯಕೆಯಿಂದ ಅಥವಾ ಹಮ್ಮಿನಿಂದ\nದೇಹವನ್ನು ಬಳಲಿಸಿ, ದಂಡಿಸಿ ಮಾಡುವ ಕರ್ಮ ರಾಜಸ ಎನಿಸುತ್ತದೆ.\n\nಮಾಡುವ ಕೆಲಸವೇನೋ ಒಳ್ಳೆಯ ಕೆಲಸವೆ. ಆದರೆ ಅದರ ಹಿಂದೆ ಅನೇಕ ಕಾಮನೆ, ನಾನುಮಾಡಿದೆ ಅನ್ನು ವ\nಅಹಂಕಾರ ಸೇರಿದಾಗ ಅದು ರಾಜಸ ಕರ್ಮವೆನಿಸುತ್ತದೆ. ನಮ್ಮ ಯಾವುದೋ ಸಮಸ್ಯೆಯ ಪರಿಹಾರಕ್ಕಾಗಿ\nಕರ್ಮ ಮಾಡುವುದು, ಕರ್ಮ ಮಾಡುವಾಗ ಅನೇಕ ಫಲದ ಅಪೇಕ್ಷೆಯಿಂದ ಮಾಡುವುದು, ಮಾಡಿದ ಮೇಲೆ\n'ನಾನು ಮಾಡಿದೆ' ಎಂದು ಅಹಂಕಾರಪಡುವುದು ರಾಜಸ ಕರ್ಮದ ಲಕ್ಷಣ. ಜೀವನಪೂರ್ತಿ ಯಾವುದೋ\nಕಾಮನೆಯ ಬೆನ್ನು ಹತ್ತಿ, ನಾಳೆಯ ಸುಖವನ್ನು ಬಯಸಿ, ಇದ್ದ ಇಂದಿನ ಸುಖವನ್ನು ಮರೆತು ದೇಹವನ್ನು ಬಳಲಿಸಿ\nಮಾಡುವ ಕರ್ಮ ರಾಜಸ ಕರ್ಮ.\n",
  "18.25": "ಅನುಬಂಧಂ ಕ್ಷಯಂ ಹಿಂಸಾಮ್‌ ಅನಪೇಕ್ಷ್ಯ ಚ ಪೌರುಷಮ್‌ ।\nಮೋಹಾತ್‌ ಆರಭ್ಯತೇ ಕರ್ಮ ಯತ್‌ ತತ್‌ ತಾಮಸಮ್‌ ಉಚ್ಯತೇ - ಪರಿಣಾಮ, ಪೋಲು, ತೊಂದರೆಗಳನ್ನು\nಗಮನಿಸದೆ, ತನ್ನ ಳವನ್ನು ಮೀರಿ ತಿಳಿಗೇಡಿತನದಿಂದ ತೊಡಗುವ ಕರ್ಮ ತಾಮಸ ಎನಿಸುತ್ತದೆ.\n\nತನ್ನ ಯೋಗ್ಯತೆಯನ್ನು ತಿಳಿದುಕೊಳ್ಳದೆ, ಮುಂದೇನಾಗುತ್ತದೆ ಎನ್ನುವ ಯೋಚನೆಯನ್ನೂ ಮಾಡದೆ, ಫಲಾಪೇಕ್ಷೆ,\nದುಡುಕು, ಅಹಂಕಾರ, ದ್ವೇಷದಿಂದ; ಭಗವಂತನನ್ನು ಮರೆತು ಮಾಡುವ ಸಮಾಜ ವಿನಾಶಕವಾದ ಕರ್ಮ\nತಾಮಸ ಕರ್ಮ. ಇದಕ್ಕೆ ಉತ್ತಮ ದೃಷ್ಟಾಂತ ದುರ್ಯೋಧನ ಮಾಡಿದ ಕರ್ಮಗಳು. ಮುಂದೆ ಆಗುವ ದುರಂತದ\nಬಗ್ಗೆ ಯೋಚಿಸದೆ, ಇನ್ನೊಬ್ಬರಿಗೆ ಕೆಟ್ಟದ್ದಾಗಬೇಕು ಎನ್ನುವ ಅನಿಷ್ಟ ಚಿಂತನೆಯಿಂದ ಮಾಡುವ ಕರ್ಮ ತಾಮಸ.\nಒಳ್ಳೆಯ ಕರ್ಮವೂ ಕೆಟ್ಟ ಉದ್ದೇಶದಿಂದ ಮಾಡಿದಾಗ ತಾಮಸವಾಗುತ್ತದೆ.\n\nಜ್ಞಾನ ಮತ್ತು ಕರ್ಮದಲ್ಲಿ ತ್ರೈವಿದ್ಯದ ವಿಧವನ್ನು ಹೇಳಿದ ಕೃಷ್ಣ ಮುಂದೆ “ಕರ್ತಾ'ನಲ್ಲಿ ಮೂರು ವಿಧವನ್ನು\nವಿವರಿಸುತ್ತಾನೆ.\n",
  "18.26": "ಮುಕ್ತ ಸಂಗಃ ಅನಹಂವಾದೀ ಧೃತಿ ಉತ್ಸಾಹ ಸಮನ್ವಿತಃ |\nಸಿದ್ಧಿ ಅಸಿಧ್ಯೋಃ ನಿರ್ವಿಕಾರಃ ಕರ್ತಾ ಸಾತ್ತ್ವಿಕಃ ಉಚ್ಯತೇ -- ಹಚ್ಚಿಕೊಳ್ಳದವನು, ನಾನು ಮಾಡಿದೆ ಎಂದು\nಕೊಚ್ಚಿಕೊಳ್ಳದವನು, ಹುರುಪಳಿಯದ ಗಟ್ಟಿಗ, ಗಳಿಕೆ-ಅಳಿಕೆಗಳಿಂದ ವಿಚಲಿತನಾಗದವನು ಸಾತ್ವಿಕ ಕರ್ತಾರ\n\nಎನಿಸುತ್ತಾನೆ.\n\nಸಾತ್ವಿಕ ಕರ್ತಾ ಯಾವುದನ್ನೂ ಅಂಟಿಸಿಕೊಳ್ಳುವುದಿಲ್ಲ. ಹೇಗೆ ಯಾವುದೇ ಪೂಜೆಯ ಕೊನೆಯಲ್ಲಿ ಶ್ರೀ\nಕೃಷ್ಣಾರ್ಪಣಮಸ್ತು' ಎಂದು ಅರ್ಪಿಸುವ ಪದ್ಧತಿ ಇದೆಯೋ ಹಾಗೇ ಸಾತ್ವಿಕ ತನ್ನ ಜೀವನದಲ್ಲಿ ತಾನು ಮಾಡುವ\nಎಲ್ಲಾ ಕರ್ಮವನ್ನು ಭಗವದ್‌ ಭಕ್ತಿಯಿಂದ ಭಗವದರ್ಪಣಾಭಾವದಿಂದ ಮಾಡುತ್ತಾನೆ. ಅವನಿಗೆ “ನಾನು ಮಾಡಿದೆ'\nಎನ್ನು ವ ಅಹಂಕಾರವೇ ಇಲ್ಲ. ಯಾವುದೇ ಕೆಲಸವಿರಲಿ ಆತ ಅದನ್ನು ಅತ್ಯುತ್ಸಾ ಹದಿಂದ ಮಾಡುತ್ತಾನೆ. ಮಾಡಿದ\nಕೆಲಸ ಕೈಗೂಡದಿದ್ದಾಗ ಆತ ಕುಸಿಯುವುದಿಲ್ಲ, ಯಶಸ್ವೀಯಾದಾಗ ಹಾರಾಡುವುದಿಲ್ಲ. ಎಲ್ಲವನ್ನು\nನಿರ್ವಿಕಾರನಾಗಿ ಮಾಡುತ್ತಾನೆ. ಇದನ್ನೇ ದ್ವಾದಷಸ್ತೋತ್ರದಲ್ಲಿ ಆಚಾರ್ಯರು ಈ ರೀತಿ ಸುಂದರವಾಗಿ\nಹೇಳಿದ್ದಾರೆ:\n\nಕುರು ಭುಂಕ್ಷ್ವ ಚ ಕರ್ಮ ನಿಜಂ ನಿಯತಂ ಹರಿಪಾದವಿನಮ್ರಧಿಯಾ ಸತತಂ |\n\nಹರಿರೇವ ಪರೋ ಹರಿರೇವ ಗುರುಃ ಹರಿರೇವ ಜಗತ್ಪಿತೃಮಾತೃಗತಿಃ ॥\n\nನಿನ್ನ ಪಾಲಿನ ಕರ್ಮ ನೀನು ಮಾಡು. ಬಂದುದನುಣ್ಣು. ಹರಿಪಾದದ ಸ್ಮರಣೆ ತಪ್ಪದಿರಲಿ-ಇದು ಸಾತ್ವಿಕನ\nಜೀವನದ ಮೂಲ ಮಂತ್ರ.\n",
  "18.27": "ರಾಗೀ ಕರ್ಮಫಲ ಪ್ರೇಪ್ಸು ಲುಬ್ಬಃ ಹಿಂಸಾ ಆತ್ಮಕಃ ಅಶುಚಿಃ ।\nಹರ್ಷ ಶೋಕ ಅನ್ವಿತಃ ಕರ್ತಾ ರಾಜಸಃ ಪರಿಕೀರ್ತಿತಃ - ಹಚ್ಚಿಕೊಳ್ಳುವವ, ಫಲ ದೊರೆತಾಗ ಹಿಗ್ಗುವವ,\nಇರದಾಗ ಕುಗ್ಗುವವ -ಇಂತಹ ಕರ್ತಾರ ರಾಜಸ ಎನಿಸುತ್ತಾನೆ.\n\nರಾಜಸನಾದವನು ಒಳ್ಳೆಯ ಕೆಲಸ ಮಾಡುತ್ತಾನೆ ಆದರೆ ಅದರಲ್ಲಿ 'ಹರ್ಷ ಶೋಕ' ತುಂಬಿರುತ್ತದೆ. ಆತ ತನ್ನ\nಕೆಲಸದಲ್ಲಿ ಯಶಸ್ವಿಯಾದಾಗ ಆಕಾಶಕ್ಕೇರುತ್ತಾನೆ, ಕೆಲಸ ಕೈಗೂಡದಾಗ ಪಾತಾಳಕ್ಕೆ ಕುಸಿಯುತ್ತಾನೆ. ಇದಕ್ಕೆ\nಮೂಲ ಕಾರಣ ರಾಜಸನಾದವನು ತನ್ನ ಪ್ರತಿಯೊಂದು ಕರ್ಮವನ್ನು ಫಲಾಪೇಕ್ಷೆಯಿಂದಲೇ ಮಾಡುವುದು. ಆತ\nಕರ್ಮವನ್ನು ಅಂಟಿಸಿಕೊಂಡು ಕರ್ಮಫಲದ ನಿರೀಕ್ಷೆಯಲ್ಲಿ ಕರ್ತವ್ಯ ನಿರ್ವಹಿಸುತ್ತಿರುತ್ತಾನೆ. ಮಾಡುವ\nಕಾರ್ಯದಲ್ಲಿ ಲೋಭ, ಶ್ರದ್ಧೆ ಇಲ್ಲದೇ ಮಾಡುವುದು, ಕರ್ಮ ಮಾಡುವಾಗ ಮಾನಸಿಕ ಸ್ವಚ್ಛತೆ ಇಲ್ಲದೇ ಇರುವುದು\nರಾಜಸನಾದವನ ಸ್ವಭಾವ.\n",
  "18.28": "ಅಯುಕ್ತಃ ಪ್ರಾಕೃತಃ ಸ್ವಬ್ಧಃ ಶಠಃ ನೈಕೃತಿಕಃ ಅಲಸಃ |\n\nವಿಷಾದೀ ದೀರ್ಫ್ಥಸೂತ್ರೀ ಚ ಕರ್ತಾ ತಾಮಸಃ ಉಚ್ಯತೇ - ನಡೆಗೇಡಿ, ಅಸಂಸ್ಕೃತ[ಭಗವಂತನಲ್ಲಿ\nಭಕ್ತಿಯಿರದವ], ಹಿರಿಮೆಗೆ ತಲೆ ಬಾಗದವ, ಉದ್ಧಟ, ಮೋಸಗಾರ, ಸೋಮಾರಿ, ಹುರುಪಿರದವ, ಇನ್ನೊಬ್ಬರ\nತಪ್ಪನ್ನೇ ಅನುಗಾಲ ಟೀಕಿಸುವವ [ಮತ್ತೆ ಮಾಡಿದರೆ ಸರಿ ಎಂದು ಕೆಲಸವನ್ನು ಸುಮ್ಮನೆ ಮುಂದೂಡುವವ]-\n\nಇಂತಹ ಕರ್ತಾರ ತಾಮಸ ಎನಿಸುತ್ತಾನೆ.\n\nತಾಮಸರಲ್ಲಿ ಅನೇಕ ವಿಧ.\n\n(೧)ಅಯುಕ್ತಃ . : ಮಾಡುವ ಕೆಲಸದಲ್ಲಿ ನಂಬಿಕೆ ಶ್ರದ್ಧೆ ಇಲ್ಲದೇ ಇರುವುದು. ಕರ್ಮ ಮಾಡುವಾಗ ಕರ್ಮ\nನಿಯಾಮಕನಾದ ಭಗವಂತನಲ್ಲಿ ಮನೋಯೋಗವೇ ಇಲ್ಲದಿರುವುದು.\n\n(೨)ಪ್ರಾಕೃತಃ : ದೇವರ ಮೇಲೆ ನಂಬಿಕೆಯೇ ಇಲ್ಲದವರು. ಕೇವಲ ಪ್ರಾಕೃತ ಪ್ರಪಂಚದಲ್ಲಿ ಆಸಕ್ತಿ ಉಳ್ಳವರು.\n(೩)ಸ್ತಬ್ಧಃ : ತಾನು ಮಾಡುವ ಕರ್ಮದಲ್ಲಿ ತಪ್ಪಿದ್ದರೂ ಕೂಡಾ ಅದನ್ನು ತಿದ್ದಿಕೊಳ್ಳದೇ, ತಿಳುವಳಿಕೆ ಇಲ್ಲದೇ, ತಪ್ಪು\nನಂಬಿಕೆಯನ್ನೇ ಆಚರಿಸಿಕೊಂಡು ಸಾಗುವವರು.\n\n(೪)ಶಠಃ : ತಪ್ಪು ಎಂದು ಗೊತ್ತಿದ್ದರೂ ತಿದ್ದಿಕೊಳ್ಳುವ ಅಪೇಕ್ಷೆ ಇಲ್ಲದೇ ಇರುವವರು. ನಾನೇಕೆ ತಲೆ ತಗ್ಗಿಸಬೇಕು\nಎನ್ನುವ ಮನೋವೃತ್ತಿ ಇರುವವರು.\n\n(೫)ನೈಕೃತಿಕಃ : ಒಳ್ಳೆಯತನದ ವೇಷಹಾಕಿಕೊಂಡು ಬುದ್ಧಿಪೂರ್ವಕವಾಗಿ ಇನ್ನೊಬ್ಬರಿಗೆ ಮೋಸಮಾಡಿ\nಲಾಭಪಡೆಯುವವರು.\n\n(೬)ಅಲಸಃ : ಯಾವುದು ಒಳ್ಳೆಯದು ಎನ್ನುವುದು ಗೊತ್ತಿದೆ ಆದರೆ ಮಾಡಲು ಸೋಮಾರಿತನ ಇರುವವರು.\n(೭)ವಿಶಾದೀ: ಒಂದು ಕ್ರಿಯೆಯನ್ನು \"ಅಯ್ಯೋ ಮಾಡಬೇಕಲ್ಲಾ' ಎಂದು ಮಾಡುವವರು. ಮಾಡಿದ ಮೇಲೂ ಮತ್ತೆ\nಬೇಸರ ವ್ಯಕ್ತಪಡಿಸುವವರು.\n\n(೮)ದೀರ್ಥಸೂತ್ರಿ: ಮತ್ತೆ ಮಾಡಿದರಾಯ್ತು ಎಂದು ದೀರ್ಥಕಾಲ ಕೆಲಸವನ್ನು ಮುಂದೂಡುವವರು. ಇನ್ನೊಬ್ಬರ\nಒಳ್ಳೆಯಗುಣವನ್ನು ಕಾಣದೇ ಅವರ ಯಾವುದೋ ಹಳೆಯ ತಪ್ಪನ್ನೇ ಎತ್ತಿ ಹೇಳುವವರು.\n\nಇಲ್ಲಿ ಹೇಳಿರುವ ಯಾವ ಒಂದು ಗುಣವಿದ್ದರೂ ಕೂಡಾ ಆತ ತಾಮಸಸೆನಿಸುತ್ತಾನೆ. ಉದಾಹರಣೆಗೆ ಈ ಎಲ್ಲಾ\nಗುಣಗಳಿದ್ದ ವ್ಯಕ್ತಿ ಮಹಾಭಾರತದ ದುರ್ಯೋಧನ.",
  "18.29": "ಬುದ್ಧೇಃ ಭೇದಮ್‌ ಧೃತೇಃ ಚ ಏವ ಗುಣತಃ ತ್ರಿವಿಧಮ್‌ ಶೃಣು |\nಪ್ರೋಚ್ಯಮಾನಮ್‌ ಅಶೇಷೇಣ ಪೃಥಕ್‌ ತ್ವೇನ ಧನಂಜಯ -- ಧನಂಜಯಾ, ಬುದ್ಧಿ ಮತ್ತು ಧೈರ್ಯ ಕೂಡಾ\nಗುಣದಿಂದ ಮೂರು ಬಗೆ. ಪೂರ್ತಿಯಾಗಿ ಅದರ ಪ್ರತ್ಯೇಕ ವಿವರಣೆಯನ್ನಾ ಲಿಸು.\n\nದೇಹ ಮತ್ತು ಇಂದ್ರಿಯಗಳು ಪೂರ್ಣಪ್ರಮಾಣದಲ್ಲಿ ವಿಕಸನ ಹೊಂದಿರುವುದು ಮಾನವರಲ್ಲಿ. ಅದಕ್ಕಾಗಿ\nಮಾನವ ಶರೀರವನ್ನು “ಪುರ' ಎನ್ನುತ್ತಾರೆ. ಈ ದೇಹದಲ್ಲಿರುವ ಜೀವನಿಗೆ(ಪುರುಷ) ಬುದ್ಧಿ ಮತ್ತು ಧೃತಿ ಬಹಳ\nಮುಖ್ಯವಾದ ಅಂಶ. ನಾವು ನಮ್ಮ ಜೀವನದಲ್ಲಿ ಹೇಡಿಗಳಾಗದೆ ಬುದ್ಧಿವಂತರಾಗಿ ಬದುಕಬೇಕು. ಈ ಬುದ್ಧಿ ಮತ್ತು\nಧೃತಿಯಲ್ಲಿ ಕೂಡಾ ಮೂರು ವಿಧ. ಸಾತ್ವಿಕ, ರಾಜಸ ಮತ್ತು ತಾಮಸ. ನಾವು ನಮ್ಮ ಜೀವನದಲ್ಲಿ ರಾಜಸ ಮತ್ತು\nತಾಮಸವನ್ನು ಅನುಸರಿಸಬಾರದು. ಅದಕ್ಕಾಗಿ ಯಾವುದು ರಾಜಸ ಯಾವುದು ತಾಮಸ ಎನ್ನುವ ವಿಚಾರ\nನಮಗೆ ತಿಳಿದಿರಬೇಕು. “ಬುದ್ಧಿ ಮತ್ತು ಧೃತಿಯಲ್ಲಿ ಮೂರು ಬಗೆಯನ್ನು ಪೂರ್ಣವಾಗಿ, ಬಿಡಿಬಿಡಿಯಾಗಿ\nಹೇಳುತ್ತೇನೆ-ಅದನ್ನು ಗಮನವಿಟ್ಟು ಕೇಳು” ಎಂದು ಕೃಷ್ಣ ಅರ್ಜುನನಲ್ಲಿ ಹೇಳುತ್ತಾನೆ. ನಾವು ಸಾತ್ವಿಕ\nಧೃತಿಯನ್ನು ಗೆದ್ದು ಧನಂಜಯರಾಗಬೇಕು ಎನ್ನುವುದು ಕೃಷ್ಣನ ಈ ಸಂದೇಶದ ಮೂಲ ಉದ್ದೇಶ.",
  "18.30": "ಪ್ರವೃತ್ತಿಮ್‌ ಚ ನಿವೃತ್ತಿಮ್‌ ಚ ಕಾರ್ಯ ಅಕಾರ್ಯೇ ಭಯ ಅಭಯೇ ।\nಬಂಧಂ ಮೋಕ್ಷಮ್‌ ಚ ಯಾ ವೇತ್ರಿ ಬುದ್ಧಿಃ ಸಾ ಪಾರ್ಥ ಸಾತ್ತ್ವಿಕೀ - ಪಾರ್ಥಾ, ಇಹದ ಧರ್ಮ-ಪರದ ಧರ್ಮ,\nಮಾಡಬೇಕಾದ್ದು-ಮಾಡಬಾರದ್ದು, ಅಂಜಬೇಕಾದ್ದು- ಅಂಜಬಾರದ್ದು, ಬಂಧನದ ದಾರಿ- ಬಿಡುಗಡೆಯ ದಾರಿ\n\nಇವನ್ನೆ ಲ್ಲಾ ಅರಿಯಬಲ್ಲ ಬುದ್ಧಿಯೇ ಸಾತ್ವಿಕ ಬುದ್ಧಿ.\n\nನಮ್ಮ ಜೀವನದಲ್ಲಿ ಮುಖ್ಯವಾಗಿ ಎದುರಾಗುವ ಸಮಸ್ಯೆ ಏನೆಂದರೆ 'ಒಂದು ಕೆಲಸವನ್ನು ಮಾಡಬೇಕೋ\nಬೇಡವೋ' ಎನ್ನುವ ಗೊಂದಲ. ಯಾವುದನ್ನು ಹಿಡಿಯಬೇಕು, ಯಾವುದನ್ನು ಬಿಡಬೇಕು; ಯಾವುದು ಒಳ್ಳೆಯ\nಕೆಲಸ, ಯಾವುದು ಕೆಟ್ಟ ಕೆಲಸ ಎನ್ನುವ ತೀರ್ಮಾನ; ನನ್ನ ಕರ್ತವ್ಯ ಯಾವುದು ಎಂದು ತಿಳಿದಿರುವುದು; ಧರ್ಮ-\nಅಧರ್ಮಗಳು; ಪಾಪ-ಪುಣ್ಯಗಳು; ಭಯ-ಅಭಯ; ಬಂಧನದ ಮತ್ತು ಬಿಡುಗಡೆಯ ದಾರಿ- ಇವೆಲ್ಲವುದರ ಬಗ್ಗೆ\nಖಚಿತವಾದ ನಿರ್ಧಾರ ಸಾತ್ವಿಕ ಮನಸ್ಸಿ ಗಿರುತ್ತದೆ. ಇದು ಸ್ವಾರ್ಥದ ಸುಳಿವೇ ಇಲ್ಲದ(ಅಪಾರ್ಥ)-ಪ್ರಜ್ಞೆ; ಜ್ಞಾನದ\nಆಳಕ್ಕೆ ಇಳಿದಾಗ ಬರುವ-ಪ್ರಜ್ಞೆ; ಬುದ್ಧಿ ವಿಸ್ತಾರವಾದಾಗ(ಪಾರ್ಥ) ಬರುವ-ಪ್ರಜ್ಞೆ. ವಿಶ್ಚೇಷಣೆ ಮಾಡಿ ನಾವು\nಸರಿಯಾದ ದಾರಿಯಲ್ಲಿ ಹೋಗುವಂತೆ ತೀರ್ಮಾನ ಮಾಡತಕ್ಕಂತಹ-ವಿವೇಕಪ್ರಜ್ಞೆ. ನಮಗೆ ನಮ್ಮ ಆತ್ಮಸಾಕ್ಷಿ\nಎಂದೂ ಮೋಸ ಮಾಡುವುದಿಲ್ಲ. ಪ್ರತಿಯೊಬ್ಬನ ಆತ್ಮಸಾಕ್ಷಿ ಕೊಡುವ ನಿರ್ಧಾರ ಖಚಿತವಾದ\nನಿರ್ಧಾರವಾಗಿರುತ್ತದೆ ಮತ್ತು ಅದು ಸಾತ್ವಿಕ.\n",
  "18.31": "ಯಯಾ ಧರ್ಮಮ್‌ ಅಧರ್ಮಮ್‌ ಚ ಕಾರ್ಯಮ್‌ ಚ ಅಕಾರ್ಯಮ್‌ ಏವ ಚ ।\nಅಯಥಾವತ್‌ ಪ್ರಜಾನಾತಿ ಬುದ್ಧಿಃ ಸಾ ಪಾರ್ಥ ರಾಜಸೀ - ಪಾರ್ಥಾ, ಯಾವುದು ಧರ್ಮ -ಯಾವುದು ಅಧರ್ಮ,\nಯಾವುದು ಮಾಡಬೇಕಾದ್ದು -ಯಾವುದು ಮಾಡಬಾರದ್ದು ಎನ್ನು ವುದನ್ನು ಸರಿಯಾಗಿ ನಿರ್ಧರಿಸಲಾಗದ ಬುದ್ಧಿ\n\nಕೆಲವೊಮ್ಮೆ ಧರ್ಮವನ್ನೇ ಅಧರ್ಮ ಎಂದು ತಿಳಿಯುವುದು ಅಥವಾ ಅಧರ್ಮವನ್ನೇ ಧರ್ಮವೆಂದು\nತಿಳಿಯುವುದು; ಇನ್ನು ಕೆಲವೊಮ್ಮೆ ಯಾವುದು ಸರಿ ಯಾವುದು ತಪ್ಪು ಎನ್ನುವ ಗೊಂದಲದಲ್ಲಿ ಬೀಳುವುದು-\nರಾಜಸ ಬುದ್ಧಿ. ಜೀವನದಲ್ಲಿ ಉಪಯೋಗಕ್ಕೆಬಾರದ ಈ ವಿಧವಾದ ಬುದ್ಧಿ, ಯಾವುದು ಮಾಡಬೇಕಾದದ್ದು-\nಯಾವುದು ಮಾಡಬಾರದ್ದು ಎನ್ನುವುದನ್ನು ಸರಿಯಾಗಿ ನಿರ್ಧರಿಸಲಾರದು.\n",
  "18.32": "ಅಧರ್ಮಮ್‌ ಧರ್ಮಮ್‌ ಇತಿ ಯಾ ಮನ್ಯತೇ ತಮಸಾ ಆವೃತಾ |\nಸರ್ವ ಅರ್ಥಾನ್‌ ವಿಪರೀತಾನ್‌ ಚ ಬುದ್ಧಿಃ ಸಾ ಪಾರ್ಥ ತಾಮಸೀ -ಪಾರ್ಥಾ, ಅಧರ್ಮವನ್ನೆ ೀ ಧರ್ಮವೆಂದು\nಗ್ರಹಿಸುವ, ಹೀಗೆ ಎಲ್ಲಾ ಸಂಗತಿಯನ್ನು ವಿಪರೀತವಾಗಿಯೇ ಗ್ರಹಿಸುವ, ಕತ್ತಲು ಕವಿದ ಬುದ್ಧಿ ತಾಮಸ ಬುದ್ಧಿ.\n\nಇರುವ ವಿಷಯವನ್ನು ಯಥಾವತ್ತಾಗಿ ಗ್ರಹಿಸದೆ, ವ್ಯತಿರಿಕ್ತವಾಗಿಯೇ ಗ್ರಹಿಸುವ ಬುದ್ಧಿ ತಾಮಸ. ಇವರು\nದುಃಖವನ್ನು ದುಃಖವೆಂದು ಗ್ರಹಿಸದೆ ಸುಖವೆಂದು ಗ್ರಹಿಸುತ್ತಾರೆ. ಉದಾಹರಣೆಗೆ ಮದ್ಯಪಾನ ಮಾಡುವುದು\nಆನಂದ ಎಂದು ಭ್ರಮಿಸಿ ಮದ್ಯಪಾನ ವ್ಯಸನಿಗಳಾಗುವುದು. ಜ್ಞಾನವನ್ನೇ ಅಜ್ಞಾನವೆಂದು ತಿಳಿದು, ತಮ್ಮ\nವಿಪರೀತ ಜ್ಞಾನವನ್ನೇ ಸರ್ವಸ್ವವಾಗಿರಿಸಿಕೊಂಡು, ಇನ್ನೊಬ್ಬರ ಮಾತಿಗೆ ಕಿವಿಗೊಡದಂತೆ ಮಾಡುವ ಬುದ್ಧಿ\n\nತಾಮಸ ಬುದ್ಧಿ.\n\nಯಾರಿಗೆ ಒಳ್ಳೆಯ ಬುದ್ಧಿ ಇದೆಯೋ ಅವರಿಗೆ ಧೃತಿ ಇರುತ್ತದೆ. ಅಜ್ಞಾನದಿಂದ-ಭಯ, ಅರಿವಿನಿಂದ-ಅಭಯ.\nವೇದಾಂತವಿರುವುದೇ ಅಭಯಕ್ಕಾಗಿ, ಮನಸ್ಸಿಗೆ ಧೈರ್ಯ ತುಂಬಿ. ಮನುಷ್ಯನನ್ನು ನಿರ್ಭಯನನ್ನಾಗಿ\nಮಾಡುವುದಕ್ಕೋಸ್ಕರ.\n\n'ಧೃತಿ' ಎನ್ನುವುದರ ಮೇಲ್ನೊ ೀಟದ ಅರ್ಥ -ಧೈರ್ಯ, ಆತ್ಮವಿಶ್ವಾಸ, ಎದೆಗಾರಿಕೆ\nಇತ್ಯಾದಿ. ಇದರ ಪೂರ್ಣ ಪ್ರಮಾಣದ ಅರ್ಥ ಇನ್ನೂ ವಿಶಾಲ. ಅಷ್ಟಾಂಗಜಪದಲ್ಲಿ(ಯಮ, ನಿಯಮ, ಆಸನ,\nಪ್ರಾಹಾಯಾಮ, ಪ್ರತ್ಯಾಹಾರ, ಧ್ಯಾನ, ಧಾರಣ ಮತ್ತು ಸಮಾಧಿ) ಹೇಳುವ \"ಧಾರಣ”-ಧೃತಿ. ಒಂದು\nವಿಷಯವನ್ನು ಗ್ರಹಿಸಿ ಅದನ್ನು ಮನಸ್ಸಿನಲ್ಲಿಟ್ಟುಕೊಳ್ಳುವುದು ಧೃತಿ. ಇಂತಹ ಧೃತಿಯಲ್ಲೂ ಮೂರು ವಿಧ-ಸಾತ್ವಿಕ,\nರಾಜಸ ಮತ್ತು ತಾಮಸ. ಇದರ ಸುಂದರ ವಿವರಣೆಯನ್ನು ಮುಂದಿನ ಮೂರು ಶ್ಲೋಕಗಳಲ್ಲಿ ಕಾಣಬಹುದು.\n",
  "18.33": "ಧೃತ್ಯಾ ಯಯಾ ಧಾರಯತೇ ಮನಃ ಪ್ರಾಣ ಇಂದ್ರಿಯ ಕ್ರಿಯಾಃ ।\n\nಯೋಗೇನ ಅವ್ಯಭಿಚಾರಿಣ್ಯಾ ಧೃತಿಃ ಸಾ ಪಾರ್ಥ ಸಾತ್ತ್ವಿಕೀ - ಪಾರ್ಥಾ, ಭಕ್ತಿಯೋಗದಿಂದ ಬಗೆಗೊಂಡು ಯಾವ\nಗಟ್ಟಿತನದ ಮನಸ್ಸು, ಪ್ರಾಣ ಮತ್ತು ಇಂದ್ರಿಯಗಳ ವ್ಯಾಪಾರಗಳನ್ನು ದಾರಿಗೆಡದಂತೆ ಧರಿಸಬಲ್ಲುದೋ ಅದು\nಸಾತ್ವಿಕ ಧೈರ್ಯ.\n\nಯಾವ ಧೃತಿಯಿಂದ ಮನಸ್ಸು, ದೇಹ, ಇಂದ್ರಿಯಗಳು ದಾರಿತಪ್ಪದೆ. ಒಂದಕ್ಕೊಂದು ಪೂರಕವಾಗಿ\nಭಕ್ತಿಯೋಗದಲ್ಲಿ ಕೆಲಸ ಮಾಡುತ್ತೇವೆ-ಅಂತಹ ಧೃತಿ ಸಾತ್ವಿಕ ಧೃತಿ. ಮನಸ್ಸು ಯಥಾವತ್ತಾದದ್ದನ್ನು ಗ್ರಹಿಸುತ್ತದೆ,\nಇಂದ್ರಿಯಗಳು ಮತ್ತು ದೇಹ ಅದಕ್ಕೆ ಪೂರಕವಾಗಿ, ಭಕ್ತಿಯಿಂದ ಕೆಲಸ ಮಾಡುತ್ತವೆ. ಇಲ್ಲಿ ಯೋಗ ಎಂದರೆ\nಭಗವದ್‌ ಭಕ್ತಿಗೆ ಪೂರಕವಾಗಿ ವಾಸ್ತವವನ್ನು ಗ್ರಹಿಸುವ ಉಪಾಯ- ಅದೇ ನಮ್ಮ ಆತ್ಮವಿಶ್ವಾಸ. ಇದರಲ್ಲಿ\n\nಅನೇಕ ಮುಖಗಳಿವೆ. ಉದಾಹರಣೆಗೆ “ತಪ್ಪನ್ನು ತಪ್ಪು ಎಂದು ಹೇಳುವ ಧೈರ್ಯ'. ಸಾಮಾನ್ಯವಾಗಿ ತಪ್ಪನ್ನು\nತಪ್ಪು ಎಂದು ಹೇಳಲು ಅನೇಕ ತೊಂದರೆಗಳಿರುತ್ತವೆ. ಇದಕ್ಕೆ ಮೊದಲ ಅಡ್ಡಿ-ದಾಕ್ಷಿಣ್ಯ. ಭಗವದ್‌ ಭಕ್ತಿಗೆ\nಪೂರಕವಾದದ್ದನ್ನು ನಾವು ನಿರ್ದಯವಾಗಿ ಹೇಳಿಬಿಡಬೇಕು. ದೈರ್ಯವಾಗಿ ತಪ್ಪನ್ನು ಪ್ರತಿಭಟಿಸಬೇಕು. ತಪ್ಪು\nಗ್ರಹಿಕೆ ಮಾಡದೆ, ತಪ್ಪು ದಾರಿಯಲ್ಲಿ ಸಾಗದೆ, ಭಗವದ್‌ ಭಕ್ತಿಗೆ ವಿರುದ್ಧವಾಗಿ ನಡೆದುಕೊಳ್ಳದೆ, ಸತ್ಯವನ್ನು\nನಿಷ್ಠುರವಾಗಿ ಹೇಳುವುದು ಸಾತ್ವಿಕ ಧೃತಿ. ಮನಸ್ಸು ಕೆಟ್ಟದ್ದನ್ನು ಯೋಚಿಸದೇ ಇರುವುದು, ದೇಹ ಕೆಟ್ಟದ್ದರ ಕಡೆ\nಚಲಿಸದೇ ಇರುವುದು, ಇಂದ್ರಿಯಗಳು ಕೆಟ್ಟದ್ದನ್ನು ಗ್ರಹಿಸದೇ ಇರುವುದು- ಹೀಗೆ ಭಗವದ್‌ ಭಕ್ತಿಗೆ\nಪೂರಕವಾಗಿರುವ ಎಲ್ಲವೂ ಸಾತ್ವಿಕ ಧೃತಿ.\n\nಸಾಮಾನ್ಯವಾಗಿ ನಾವು ನಮ್ಮ ದೇಹ ಇಂದ್ರಿಯಗಳನ್ನು ನಿಯಂತ್ರಿಸಬಹುದು, ಆದರೆ ಮನಸ್ಸು ಕೆಟ್ಟದ್ದನ್ನು\nಯೋಚಿಸದಂತೆ ನಿಯಂತ್ರಿಸುವುದು ಬಹಳ ಕಷ್ಟದ ಕೆಲಸ. ಇದನ್ನು ಸಾಧಿಸಲು ಧೀರ್ಥಕಾಲದ ಸಾಧನೆ ಅಗತ್ಯ.\nಈ ಎಲ್ಲಾ ವಿಷಯಗಳು ತಿಳಿದಾಗ ನಾವು ಸಾತ್ವಿಕ ಧೃತಿಯಿಂದ ಎಷ್ಟು ದೂರದಲ್ಲಿದ್ದೇವೆ ಎನ್ನುವುದು ತಿಳಿಯುತ್ತದೆ\nಮತ್ತು ನಮ್ಮನ್ನು ನಾವು ತಿದ್ದಿಕೊಂಡು ಸಾತ್ವಿಕ ಧೃತಿಯತ್ತ ಸಾಗಲು ಸಹಾಯಕವಾಗುತ್ತದೆ.\n",
  "18.34": "ಯಯಾ ತು ಧರ್ಮ ಕಾಮ ಅರ್ಥಾನ್‌ ಧೃತ್ಯಾ ಧಾರಯತೇ ಅರ್ಜುನ ।\nಪ್ರಸಂಗೇನ ಫಲ ಆಕಾಂಕ್ಷೀ ಧೃತಿಃ ಸಾ ಪಾರ್ಥ ರಾಜಸೀ - ಪಾರ್ಥಾ, ಧರ್ಮ-ಕಾಮ-ಅರ್ಥಗಳನ್ನು ಓಲೈಸುವ,\nಅತಿಯಾಗಿ ಹಚ್ಚಿಕೊಂಡು ಫಲದ ಆಸೆ ಹೊತ್ತ ಗಟ್ಟಿತನ ರಾಜಸ ಧೈರ್ಯ.\n\nತಾಯಿ ತನ್ನ ಮಗುವನ್ನು ನಿಸ್ವಾರ್ಥವಾಗಿ ಪ್ರೀತಿಸುವಂತೆ ಭಗವಂತನನ್ನು ಪ್ರೀತಿಸುವುದು ಭಕ್ತಿ. ಈ ಪ್ರೀತಿಯಲ್ಲಿ\nಫಲಾಪೇಕ್ಷೆ ಸೇರಿದರೆ ಅದು ಭಕ್ತಿ ಎನಿಸದೆ ಸ್ವಾರ್ಥ ಎನಿಸುತ್ತದೆ. ರಾಜಸ ತನ್ನ ಇಷ್ಟಾರ್ಥ ಸಿದ್ಧಿಗಾಗಿ ಆದಷ್ಟು\nಧರ್ಮದ ಚೌಕಟ್ಟಿನಲ್ಲೇ ಕಾರ್ಯ ನಿರ್ವಹಿಸಬಹುದು. ಆದರೆ ಆತ ಹಣವನ್ನು ಗಳಿಸುವುದಕ್ಕಾಗಿ ಅಥವಾ\nಅತಿಯಾದ ಮೋಹದಿಂದ ಫಲದ ಆಸೆ ಹೊತ್ತ ಗಟ್ಟಿತನ ತನ್ನದಾಗಿರಿಸಿಕೊಂಡಿರುತ್ತಾನೆ. ಇದು ರಾಜಸ ಧೃತಿ.\nನಾವು ರಾಜಸ ಗುಣದ ಸ್ಪರ್ಶವಿಲ್ಲದ, ಬಿಳಿಯಾದ(ಅರ್ಜುನ)-ಶುದ್ಧಸಾತ್ವಿಕರಾಗಬೇಕು ಎನ್ನುವುದು ಕೃಷ್ಣನ\nಸಂದೇಶ.\n",
  "18.35": "ಯಯಾ ಸ್ವಪ್ನಂ ಭಯಂ ಶೋಕಂ ವಿಷಾದಂ ಮದಮ್‌ ಏವ ಚ |\nನ ವಿಮುಂಚತಿ ದುರ್ಮೇಧಾ ಧೃತಿಃ ಸಾ ಪಾರ್ಥ ತಾಮಸೀ - ಪಾರ್ಥಾ, ನಿದ್ದೆ, ಅಂಜಿಕೆ, ದುಗುಡ, ನಿರುತ್ಸಾಹ,\nಸೊಕ್ಕುಗಳನ್ನು ಬಿಟ್ಟಿರಲಾಗದ ತಿಳಿಗೇಡಿಯ ಗಟ್ಟಿತನವೇ ತಾಮಸ ಧೈರ್ಯ.\n\nಗ್ರಹಿಕೆಯಲ್ಲಿ ತಾಮಸ ಪ್ರವೃತ್ತಿ ಉಳ್ಳವ ತಿಳಿಗೇಡಿ, ಅವಿವೇಕಿ. ಆತ ಒಳ್ಳೆಯ ಗ್ರಹಿಕೆಗಳಿಗೆ ಹೋಗುವುದೇ ಇಲ್ಲ.\nಒಳ್ಳೆಯ ವಿಷಯ ಚರ್ಚೆಯಾಗುವಾಗ ಈತ ್ಹಇನಿದ್ದೆಮಾಡುತ್ತಿರುತ್ತಾನೆ. ಈತನಿಗೆ. ಯಾವಾಗಲೂ\nಭಯ.[ಉದಾಹರಣೆಗೆ ಲಂಚ ತೆಗೆದುಕೊಳ್ಳುವುದು ಮತ್ತು ಅದರಿಂದಾಗಿ ಜೀವನಪೂರ್ತಿ ಭಯದಿಂದ\nಬಾಳುವುದು]. ಈತನ ಜೀವನದಲ್ಲಿ ಲವಲವಿಕೆ, ಉತ್ಸಾ ಹ, ಗೆಲುವು ಇರುವುದಿಲ್ಲ. ತಾನು ಶ್ರೇಷ್ಠ ಉಳಿದವರು\n\nಕನಿಷ್ಠ ಎನ್ನು ವ ಅಶಾಸ್ತ್ರೀಯವಾದ ಸಂಕಲ್ಪ ತಾಮಸ ಧೃತಿ.",
  "18.36": "ಯತ್‌ ತದಗ್ರೇ ವಿಷಮಿವ ಪರಿಣಾಮೇ5ಮೃತೋಪಮಮ್‌ |",
  "18.37": "ಸುಖಮ್‌ ತು ಇದಾನೀಮ್‌ ತ್ರಿವಿಧಮ್‌ ಶೃಣು ಮೇ ಭರತರ್ಷಭ |।\n\nಅಭ್ಯಾಸಾತ್‌ ರಮತೇ ಯತ್ರ ದುಃಖಾಂತಮ್‌ ಚ ನಿಗಚ್ಛತಿ ॥|\n\nಯತ್‌ ತತ್‌ ಅಗ್ರೇ ವಿಷಮ್‌ ಇವ ಪರಿಣಾಮೇ ಅಮೃತ ಉಪಮಮ್‌ |।\n\nತತ್‌ ಸುಖಮ್‌ ಸಾತ್ವಿಕಮ್‌ ಪ್ರೋಕ್ತಮ್‌ ಆತ್ಮ ಬುದ್ಧಿ ಪ್ರಸಾದಜಮ್‌ -- ಭರತರ್ಷಭಾ, ಈಗ ಮೂರುತೆರನಾದ\nಸುಖವನ್ನು ನನ್ನಿಂದಾಲಿಸು: ಬಳಕೆಯಿಂದ ಖುಷಿಕೊಡುವಂತಹದ್ದು, ದುಃಖವನ್ನು ನೀಗಿಸುವಂತಹದ್ದು, ಮೊದಲು\nವಿಷದಂತೆ ಅಪ್ರಿಯವಾಗಿ ಕೊನೆಗೆ ಅಮೃತದಂತೆ ಹಿತ ನೀಡುವಂತಹದ್ದು -ಇಂತಹ ಸುಖ-ಸಾತ್ವಿಕ. ಇದು ತನ್ನ\nಬಗೆ ತಿಳಿಯಾದಾಗ, ಭಗವಂತನ ಕರುಣೆಯಿಂದ ಬರುವಂತಹದ್ದು.\n\nಮನುಷ್ಯ ಒಟ್ಟಾಗಿ ಜೀವನದಲ್ಲಿ ಬಯಸುವುದು ಸುಖವನ್ನು. ಆತನ ಜೀವನದ ಕೊನೆಯ ಗುರಿ ಸುಖ. ಆದರೆ\nಯಾವುದು ನಿಜವಾದ ಸುಖ? ಸುಖದಲ್ಲೂ ಮೂರು ವಿಧ-ಸಾತ್ವಿಕ, ರಾಜಸ ಮತ್ತು ತಾಮಸ. “ತ್ರೈವಿದ್ಯೆಯ\nವಿವರಣೆಯ ಕೊನೆಯಲ್ಲಿ ಸುಖದ ಮೂರು ವಿಧದ ವಿವರಣೆಯನ್ನು ಕೇಳು” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಇಲ್ಲಿ ಬಳಸಿರುವ\n'ಭರತರ್ಷಭ' ಎನ್ನುವ ವಿಶೇಷಣದ ಹಿಂದೆ ವ್ಯಾಸರು ನಮಗೆ ಅನೇಕ ಸಂದೇಶವನ್ನು ಕೊಟ್ಟಿರುವುದನ್ನು ನಾವು\nಗಮನಿಸಬೇಕು. ಭಗವಂತನ ಭಕ್ತಿಯಲ್ಲಿ-ರತ(ಶ್ರೇಷ್ಛರಾದಾಗ; ಭರತನಂತೆ ಲೌಕಿಕ ಸುಖದ ಆಸೆ ಇಲ್ಲದೆ ಪೂರ್ಣ\nಪ್ರಮಾಣದಲ್ಲಿ ಶ್ರೀರಾಮಚಂದ್ರನನ್ನು ಪ್ರೀತಿಸಿದಾಗ; ಭಗವಂತನ ಭಕ್ತಿಯಲ್ಲಿ ನಿರತರಾದವರಲ್ಲಿ ಶ್ರೇಷ್ಠರಾದ\nವಾಯು(ಹನುಮಂತ)ದೇವರಲ್ಲಿ ಗುರುಭಕ್ತಿಯನ್ನಿಟ್ಟು, ಭಗವದರ್ಪಣಾಭಾವದಿಂದ ನಮ್ಮ ಕರ್ಮ ನಿರ್ವಹಿಸಿದಾಗ-\nನಾವು ಭರತರ್ಷಭರಾಗಬಹುದು. ಭರತರ್ಷಭನಾದವನಿಗೆ ನಿಜವಾದ ಸುಖ ಎಂದರೇನು ಎಂದು ತಿಳಿದು\nಅದನ್ನು ಅನುಭವಿಸಲು ಸಾಧ್ಯ.\n\nಯಾವುದೇ ಒಂದು ವಿಷಯ ಪ್ರಾರಂಭದಿಂದಲೇ ಸುಖವಾಗಿ ಕಾಣಿಸಿದರೆ ಅದು ಸಾತ್ವಿಕ ಸುಖವಲ್ಲ. ಕಷ್ಟಪಡದೆ\nಅನಾಯಾಸವಾಗಿ ಪಡೆಯುವುದು ಮೋಹದ ಸುಖ. ಸಾತ್ವಿಕ ಸುಖ ಮೊದಲು ಕಷ್ಟ ರೂಪದಲ್ಲಿರುತ್ತದೆ. ಇದಕ್ಕೆ\nಉತ್ತಮ ದೃಷ್ಟಾಂತ ಸಮುದ್ರಮಥನ. ಅಲ್ಲಿ ಮೊದಲು ಬಂದಿರುವುದು ಅಮೃತವಲ್ಲ ಬದಲಿಗೆ ವಿಷ. ನಿಜವಾದ\nಅಮೃತ ಸಿಕ್ಕಿರುವುದು ಕೊನೆಯಲ್ಲಿ. ಕೈಕೆಸರಾದರೆ ಬಾಯಿ ಮೊಸರು-ಕಷ್ಟಪಟ್ಟರೆ ಸುಖ. ನಾವು ಕುಡಿಯುವ\nಔಷಧ ವಿಷದಂತೆ ಕಹಿ, ಆದರೆ ಅದರಿಂದ ಬರುವ ಆರೋಗ್ಯ ಅಮೃತದಂತೆ ಸಿಹಿ.\n\nಕೃಷ್ಣ ಇಲ್ಲಿ “ಆತ್ಮ ಬುದ್ಧಿ ಪ್ರಸಾದಜಮ್‌” ಎನ್ನುವ ಒಂದು ಅಪೂರ್ವ ವಿಶೇಷಣವನ್ನು ಬಳಸಿದ್ದಾನೆ. ಆತ್ಮಪ್ರಸಾದ\nಅಂದರೆ ದೇವರ ಅನುಗ್ರಹ. ಸಾತ್ವಿಕ ಸುಖ ನಾವು ಬೇಕು ಎಂದು ಬಯಸಿದಾಗ ಸಿಗುವುದಿಲ್ಲ. ಅದು ಭಗವಂತನ\nಅನುಗ್ರಹದಿಂದ ಸಿಗುವಂತಹದ್ದು. ಅದನ್ನು ಪಡೆಯಲು ನಮಗೆ ಪಾರದರ್ಶಕವಾದ ಶುದ್ಧ ಮನಸ್ಸಿರಬೇಕು. ಅದು\nಹೊರಗಿನಿಂದ ಬರುವುದಲ್ಲ ಬದಲಿಗೆ ಒಳಗಿನಿಂದ ಚಿಮ್ಮುವುದು. ಹೀಗೆ ಭಗವಂತನ ಅನುಗ್ರಹ ಮತ್ತು ಮನಸ್ಸಿನ\nಪ್ರಸನ್ನತೆಯಿದ್ದಾಗ ಒಳಗಿನ ಸ್ವರೂಪಾನಂದದ ಸುಖವನ್ನು ಅನುಭವಿಸಲು ಸಾಧ್ಯ.\n",
  "18.38": "ವಿಷಯ ಇಂದ್ರಿಯ ಸಂಯೋಗಾತ್‌ ಯತ್‌ ತತ್‌ ಅಗ್ರೇ ಅಮೃತ ಉಪಮಮ್‌ ।\nಪರಿಣಾಮೇ ವಿಷಮ್‌ ಇವ ತತ್‌ ಸುಖಮ್‌ ರಾಜಸಮ್‌ ಸ್ಮೃತಮ್‌ -- ವಿಷಯ ಮತ್ತು ಇಂದ್ರಿಯಗಳ ನಂಟಿನಿಂದ\nಉಂಟಾಗುವಂತಹದ್ದು, ಮೊದಲು ಅಮೃತದಂತೆ ರೋಚಕ, ಕಡೆಗೆ ವಿಷದಂತೆ ಅಪಾಯಕಾರಿ -ಅಂತಹ ಸುಖ\n\nರಾಜಸ ಎನಿಸುತ್ತದೆ.\n\nಯಾವುದು. ಮೊದಲು ಅನುಭವಿಸುವಾಗ ಬಹಳ ಸುಖವನ್ನು ಕೊಟ್ಟು ಆ ನಂತರ ಪರಿಣಾಮ\nದುಃಖಕರವಾಗಿರುತ್ತದೋ ಅದು ರಾಜಸ ಸುಖ. ಇದು ಬಾಹ್ಯಸುಖ. ಇದು ಹೊರಗಿನ ವಿಷಯಗಳಿಗೂ ನಮ್ಮ\nಇಂದ್ರಿಯಗಳಿಗೂ ಸಂಪರ್ಕದಿಂದ ತತ್ಕಾಲಕ್ಕೆ ಸಿಗುವ ಸುಖ. ಇಂದು ನಾವು ಕಾಣುವ ಹೆಚ್ಚಿನ ಅಪರಾಧ\nಸುದ್ಧಿಗಳು ಈ ರೀತಿಯ ಕ್ಷಣಿಕ ಸುಖದ ಹಿಂದೆ ಹೋಗಿ ಆಗುವ ಪರಿಣಾಮ. ವಿಷಯ ಸುಖವನ್ನು\nಅನುಭವಿಸುವುದು ತಪ್ಪಲ್ಲ, ಆದರೆ ಅನುಭವಿಸಿ ಅದನ್ನು ಮೀರಿನಿಲ್ಲುವುದು ಬಹಳ ಮುಖ್ಯ. ಹಿಂದಿನವರು\nಮುಖ್ಯವಾಗಿ ಎರಡನ್ನು ಗೆಲ್ಲು ಎಂದಿದ್ದಾರೆ. ಒಂದು-ಆಹಾರದ ಚಟ ಇನ್ನೊಂದು ಲೈಂಗಿಕ ಚಪಲ. ಒಟ್ಟಿನಲ್ಲಿ\nಕ್ಷಣಿಕವಾದ ಇಂದ್ರಿಯ ಸುಖವನ್ನು ಗೆಲ್ಲುವುದು ಬಹಳ ಮುಖ್ಯ.\n",
  "18.39": "ಯತ್‌ ಅಗ್ರೇ ಚ ಅನುಬಂಧೇ ಚ ಸುಖಂ ಮೋಹನಮ್‌ ಆತ್ಮನಃ |\n\nನಿದ್ರಾ ಆಲಸ್ಯ ಪ್ರಮಾದ ಉತ್ಸಂ ತತ್‌ ತಾಮಸಮ್‌ ಉದಾಹೃತಮ್‌ -- ಮೊದಲೂ ಕೊನೆಗೂ ಮತ್ತು ಬರಿಸಿ\nಮೈಮರೆಸುವಂತಹ ಸುಖ, ನಿದ್ದೆ-ಮೈಗಳ್ಳತನ-ಎಚ್ಚರಗೇಡಿತನಗಳಿಂದ ಸಿಗುವಂತಹ ಸುಖ-ತಾಮಸ\nಎನಿಸುತ್ತದೆ.\n\nಮನುಷ್ಯನನ್ನು ವಾಸ್ತವ ಪ್ರಪಂಚದಿಂದ ಭ್ರಮೆಗೆ ತಳ್ಳಿ, ಅವನನ್ನು ಮೋಹದಬಲೆಯಲ್ಲಿ ಬೀಳಿಸಿ,\nಬುದ್ಧಿಗೇಡಿಯನ್ನಾಗಿಸಿ, ಸಂತೋಷದ ಭ್ರಮೆ ಹುಟ್ಟಿಸುವುದು ತಾಮಸ ಸುಖ. ಇದರಲ್ಲಿ ಮೊದಲೂ ಸುಖವಿಲ್ಲ,\nಕೊನೆಗೂ ಸುಖವಿಲ್ಲ. ಉದಾಹರಣೆಗೆ ಮದ್ಯಪಾನ, ಧೂಮಪಾನ ಇತ್ಯಾದಿ ಎಲ್ಲಾ ದುಶ್ಚಟಗಳು.\nಸೋಮಾರಿತನದಿಂದ ಬರುವ ಸುಖ, ನಿದ್ದೆಯಿಂದ ಬರುವ ಸುಖ, ಎಚ್ಚರಗೇಡಿತನದಿಂದ ಬರುವ ಸುಖ-ಇವು\nಒಳಗಿನ ಮನಸ್ಸನ್ನು ಕೊಂದು ಪಡೆಯುವ ಬಾಹ್ಯ ಸುಖ- ಇದು ತಾಮಸ. ಉದಾಹರಣೆಗೆ ನಿದ್ದೆ. ಮನುಷ್ಯ\nಮಗುವಾಗಿದ್ದಾಗ ಆತನಿಗೆ ಇಪ್ಪತ್ತು ಗಂಟೆ ನಿದ್ದೆ ಮತ್ತು ನಾಲ್ಕು ಗಂಟೆ ಎಚ್ಚರ ಅಗತ್ಯ. ಆದರೆ ಪ್ರಬುದ್ಧನಾದವನಿಗೆ\nನಾಲ್ಕು ಗಂಟೆ ನಿದ್ದೆ ಸಾಕು. ಆತ ಅಭ್ಯಾಸ ಮಾಡಿದರೆ ಇಪ್ಪತ್ತು ಗಂಟೆ ಎಚ್ಚರವಾಗಿರಬಹುದು. ಆದರೆ ತಾಮಸ\nಸುಖ ದಿನವಿಡೀ ನಿದ್ದೆ ಮಾಡುವುದೇ ಪರಮ ಸುಖ ಎಂದು ಭ್ರಮೆ ಹುಟ್ಟಿಸಿ ಮನುಷ್ಯನನ್ನು ದಾರಿ ತಪ್ಪಿಸುತ್ತದೆ.",
  "18.40": "ನ ತತ್‌ ಅಸ್ತಿ ಪೃಥಿವ್ಯಾಂ ವಾದಿವಿ ದೇವೇಷು ವಾ ಪುನಃ ।\n\nಸತ್ತ್ವಂ ಪ್ರಕೃತಿಜೈಃ ಮುಕ್ತಂ ಯತ್‌ ಏಭಿಃ ಸ್ಯಾತ್‌ ತ್ರಿಭಿಃ ಗುಣೈಃ -- ಭೂಮಿಯಲ್ಲಾಗಲೀ, ಸ್ವರ್ಗದಲ್ಲಿನ\nದೇವತೆಗಳಲ್ಲಾಗಲೀ, ಪ್ರಕೃತಿಯಿಂದುಟಾದ ಈ ಮೂರು ಗುಣಗಳಿಂದ ಬಿಡುಗಡೆಗೊಂಡ ಜೀವಜಾತವೆಂಬುದಿಲ್ಲ.\nತ್ರೈಗುಣ್ಯದ ಬಗ್ಗೆ ವಿವರವಾದ ಚಿತ್ರಣವನ್ನು ಕೊಟ್ಟ ನಂತರ ಕೃಷ್ಣ ಜೀವ ಸ್ವಭಾವದ ವಿವರಣೆಯನ್ನು ಕೊಡುತ್ತಾನೆ.\nಈ ಭೂಮಿಯಲ್ಲಾಗಲೀ, ಅಥವಾ ಸತ್ಯಲೋಕದ ತನಕ ಯಾವುದೇ ದೇವತಾ ಲೋಕವಿರಲೀ, ಸಮಸ್ತ\nಜೀವಜಾತಗಳು ಈ ಪ್ರಕೃತಿಯಿಂದ ನಿರ್ಮಿತವಾದ ತ್ರಿಗುಣಗಳ ಅಧೀನ. ಪ್ರತಿಯೊಂದು ಜೀವವೂ ಕೂಡಾ ಈ\nಮೂರು ಸ್ವಭಾವಕ್ಕೆ ಒಳಪಟ್ಟಿದೆ ಮತ್ತು ಪ್ರತಿಯೊಂದು ಜೀವ ಈ ಮೂರು ಗುಣಗಳ ಕಲಬೆರಕೆ. ನೂರಕ್ಕೆ ನೂರು\nಸಾತ್ವಿಕ/ರಾಜಸ/ತಾಮಸ ಯಾರೂ ಇಲ್ಲ. ಇಡೀ ಜಗತ್ತು ಮೂರರ ಮಿಶ್ರಣ.\n\nಜೀವ ಸ್ವಭಾವವನ್ನು ನೇರವಾಗಿ ಸಾತ್ವಿಕ-ರಾಜಸ-ತಾಮಸ ಎಂದು ಮೂರು ವಿಭಾಗ ಮಾಡಲು ಬರುವುದಿಲ್ಲ.\nಇದಕ್ಕಾಗಿ ಇದನ್ನು ಚಾತುರ್ವರ್ಣ್ಯ್ಯವಾಗಿ ಕೃಷ್ಣ ವಿಂಗಡಿಸಿ ಹೇಳಿದ. ಹಿಂದೆ ವಿವರಿಸಿದಂತೆ ಚಾತುರ್ವರ್ಣ್ಯ\n'“ಜಾತಿವಿಭಾಗ' ಅಲ್ಲ. ಇದು ವರ್ಣ ವಿಭಾಗ. ಭಗವದ್ಗೀತೆಯಾಗಲೀ , ವೇದವಾಗಲೀ ಜಾತಿ ವಿಭಾಗವನ್ನು\nಒತ್ತುಕೊಟ್ಟು ಹೇಳುವುದಿಲ್ಲ. ಜಾತಿವಿಭಾಗ ಕೆಲವು ಧರ್ಮ ಶಾಸ್ತ್ರಗಳಲ್ಲಿ ಬಂದಿದೆಯೇ ಹೊರತು ವೇದ ಮತ್ತು\n\nಭಗವದ್ಗೀತೆಯಲ್ಲಿ ಬಂದಿಲ್ಲ. ಜಾತಿ ಅನ್ನುವುದು ಸಮಾಜ ವ್ಯವಸ್ಥೆಗಾಗಿ ಮಾಡಿಕೊಂಡ ವಿಭಾಗ. ಆದರೆ ವರ್ಣ\nಮನಃಶಾಸ್ತ್ರೀಯವಾಗಿ ಜೀವಸ್ವಭಾವವನ್ನು ಅರಿತು ಹೇಳುವಂತಾದ್ದು.\n\nಸ್ಥೂಲವಾಗಿ ಹೇಳಬೇಕೆಂದರೆ ದೇವತೆಗಳು-ಸಾತ್ವಿಕರು, ಮಾನವರು-ರಾಜಸರು ಮತ್ತು ದೈತ್ಯರು-ತಾಮಸರು.\nಆದರೆ ಈ ವಿಭಾಗ ಇಲ್ಲಿಗೆ ಕೊನೆಗೊಳ್ಳುವುದಿಲ್ಲ. ಈ ಪ್ರತಿಯೊಂದು ವರ್ಗದಲ್ಲಿ ಮತ್ತೆ ಮೂರು ವಿಭಾಗವಿದೆ.\nಉದಾಹರಣೆಗೆ ತಾಮಸ-ಸಾತ್ವಿಕರು. . ಮನುಷ್ಯರಲ್ಲಿ. ನರಾಧಮರು. ತಾಮಸ-ಸಾತ್ವಿಕರು. ದೈತ್ಯ\nಪರಿವಾರದವರು ತಾಮಸ-ರಾಜಸರು; ಅವರನ್ನು ನಿಯಂತ್ರಿಸುವ ಕಾಲನೇಮಿಯಂತಹ ದೈತ್ಯರು ತಾಮಸ-\nತಾಮಸರು.\n\nಮಾನವರಲ್ಲಿ ರಾಜಸ-ತಾಮಸರು ನರಾಧಮರು. ರಾಜಸ-ರಾಜಸರು ಎಂದರೆ ನಿತ್ಯ ಸಂಸಾರಿಗಳು. ಅವರು\nಎಂದೂ ತಮಸ್ಸಿಗಾಗಲೀ, ಮೋಕ್ಷಕ್ಕಾಗಲೀ ಹೋಗುವುದಿಲ್ಲ. ಸದಾ ಈ ಸಂಸಾರ ಚಕ್ರದಲ್ಲಿ ಸುತ್ತುತ್ತಿರುತ್ತಾರೆ.\nಇನ್ನು ಮೂರನೆಯವರಾದ ರಾಜಸ-ಸಾತ್ವಿಕರು ಮೋಕ್ಷ ಯೋಗ್ಯರು. ಚಾತುರ್ವರ್ಣ್ಯ ಎನ್ನುವುದು ಈ ಮೂರನೇ\nಗುಂಪಿಗೆ ಮಾತ್ರ ಸೀಮಿತವಾದದ್ದು. ಆದ್ದರಿಂದ ಮೋಕ್ಷ ಯೋಗ್ಯರಾದ ರಾಜಸ-ಸಾತ್ವಿಕರಲ್ಲಿ ನಾಲ್ಕು ವಿಧ.\nಮೋಕ್ಷಯೋಗ್ಯ-ಬ್ರಾಹ್ಮಣ, ಮೋಕ್ಷಯೋಗ್ಯ- ಕ್ಷತ್ರಿಯ, ಮೋಕ್ಷಯೋಗ್ಯ-ವೈಶ್ಯ, ಮತ್ತು ಮೋಕ್ಷಯೋಗ್ಯ-ಶೂದ್ರ.\nಇದು ಜೀವ ಸ್ವಭಾವದ ಮೇಲೆ ಇರುವ ನಾಲ್ಕು ವಿಭಾಗ. ಇಲ್ಲಿ ಮೇಲು-ಕೀಳು ಎನ್ನು ವ ಭೇದವಿಲ್ಲ. ಎಲ್ಲರೂ\nಮೋಕ್ಷ ಯೋಗ್ಯರು. ಸತ್ವ ರಜಸ್ಸು ಮತ್ತು ತಮಸ್ಸಿನ ಅನುಪಾತದಂತೆ ಮತ್ತೆ ಅನೇಕ ವಿಧವನ್ನು\nಚಾತುರ್ವರ್ಣ್ಯದೊಳಗೆ ಕಾಣಬಹುದು.\n\n(೧)ಪರಮಹಂಸರು(೯೦-ಅಂಶ ಸಾತ್ವಿಕ):ಇವರು. ತಮ್ಮನ್ನು ತಾವು. ಪೂರ್ಣವಾಗಿ ಭಗವಂತನಲ್ಲಿ\nನೆಲೆಗೊಳಿಸಿಕೊಂಡವರು. ಇವರಲ್ಲಿ ರಾಜಸ ಮತ್ತು ತಾಮಸದ ಅಂಶ ಕೇವಲ ೧೦.\n\n(೨)ಹಂಸರು(೮೫-ಅಂಶ ಸಾತ್ವಿಕ): ಹಂಸರು ಪರಮಹಂಸರ ನಂತರದವರು. ಇವರಲ್ಲಿ ರಾಜಸ ಮತ್ತು\nತಾಮಸದ ಪ್ರಮಾಣ ೧೫-ಅಂಶ.\n\n(೩)ಬಹೂದಕರು(ಲ೦-ಅಂಶ ಸಾತ್ವಿಕ): ಇವರಿಗೆ ಒಂದು ಸ್ಥಿರವಾದ ನೆಲೆ ಇಲ್ಲ. ದಿನಕ್ಕೊಂದು ಕಡೆ ಇವರ ವಾಸ.\nಇವರಲ್ಲಿ ಸಾತ್ವಿಕ ಅಂಶ ೮೦ ಮತ್ತು ರಾಜಸ-ತಾಮಸ ಅಂಶ-೨೦\n\n(೪)ಕುಟೀಚಕರು(೭೫-ಅಂಶ ಸಾತ್ವಿಕ): ಇವರು ಬಹೂದಕರಂತೆ. ಆದರೆ ಇವರು ಒಂದು ಕಡೆ ಒಂದು\nಮನೆಯಲ್ಲಿ ವಾಸಿಸುವವರು. ಇವರಲ್ಲಿ ರಾಜಸ ಮತ್ತು ತಾಮಸದ ಅಂಶ-೨೫.\n\n(೫)ವಾನಪ್ರಸ್ಥರು(೭೦-ಅಂಶ ಸಾತ್ವಿಕ):ಮನೆಯಲ್ಲಿ ಗೃಹಸ್ಥರಾಗಿದ್ದು, ನಂತರ ತಮ್ಮ ಮಕ್ಕಳು\nಪ್ರಾಯಪ್ರಬುದ್ಧರಾದ ಮೇಲೆ ಕಾಡಿಗೆ ಹೋಗಿ ಸಾಧನೆ ಮಾಡುವವರು. ಇವರಲ್ಲಿ ೩೦ ಅಂಶ ರಾಜಸ-\nತಾಮಸವಿದ್ದರೆ ಉಳಿದ ೭೦-ಅಂಶ ಸಾತ್ವಿಕ. ಇವರಿಗೆ ಅಗ್ನಿ ಕರ್ಮವಿದೆ, ಸ್ತ್ರೀ-ಸಂಗವಿಲ್ಲ.\n(೬)ಬ್ರಹ್ಮಚಾರಿಗಳು(೬೫-ಅಂಶ ಸಾತ್ವಿಕ): ಇವರಲ್ಲಿ ಶೇಕಡಾ ೩೫ ಅಂಶ ರಾಜಸ ಮತ್ತು ತಾಮಸ. ಇವರಿಗೆ\nಸ್ತ್ರೀ-ಸಂಗ ನಿಷಿದ್ಧ.\n\n(೭)ಗೃಹಸ್ಥರು: ಇವರಲ್ಲಿ ಸಾತ್ವಿಕ ಅಂಶ ೬೦, ಉಳಿದ ೪೦- ರಾಜಸ ಮತ್ತು-ತಾಮಸ ಅಂಶ. ಇವರು\nಸಾಂಸಾರಿಕ ಜೀವನ ನೆಡೆಸಬಹುದು.\n\nಈ ಮೇಲಿನ ೭ ವಿಧ- ಬ್ರಾಹ್ಮಣ ವರ್ಗಕ್ಕೆ ಸಂಬಂಧಪಟ್ಟದ್ದು. ಒಟ್ಟಿನಲ್ಲಿ ಹೇಳಬೇಕೆಂದರೆ ಕನಿಷ್ಠ ೬೦-ಪ್ರಮಾಣ\nಸಾತ್ವಿಕ-ಅಂಶ ಇರುವ ಮೋಕ್ಷಯೋಗ್ಯ ಮಾನವ ಬ್ರಾಹ್ಮಣ ಎನಿಸುತ್ತಾನೆ.\n\n(ಲ)ಕ್ಷತ್ರಿಯರು(೫೫:೩೫:೧೦): ಇವರಲ್ಲಿ ಸಾತ್ವಿಕ ಅಂಶ-೫೫ ಮತ್ತು ರಾಜಸ ಅಂಶ ೩೫. ಇವರಿಗೆ ಆಡಳಿತದಲ್ಲಿ\nಆಸಕ್ತಿ. ತಮ್ಮ ತೋಳ್ಬಲದಿಂದ ಸಮಾಜದ ರಕ್ಷಣೆ ಮಾಡುವುದು ಇವರ ಕರ್ತವ್ಯ.\n\n(೯)ವೈಶ್ಯರು (೪೦:೪೦:೨೦): ಇವರಲ್ಲಿ ಸಾತ್ವಿಕ ಮತ್ತು ರಾಜಸ ಅಂಶ ಸಮನಾಗಿದೆ(೪೦). ಇವರಿಗೆ ಕೃಷಿ,\nಹೈನುಗಾರಿಕೆ, ವ್ಯಾಪಾರದಲ್ಲಿ ಆಸಕ್ತಿ.\n\n(೧೦)ಶೂದ್ರರು(೩೫:೩೫:೩೦): ಇವರು ಇಡೀ ಸಮಾಜದ ಅಡಿಪಾಯ. ಇವರು ಸೇವಾ ಮನೋವೃತ್ತಿ\nಇರುವವರು.",
  "18.41": "ಬ್ರಾಹ್ಮಣ ಕ್ಷತ್ರಿಯ ವಿಶಾಮ್‌ ಶೂದ್ರಾಣಾಮ್‌ ಚ ಪರಂತಪ ।\nಕರ್ಮಾಣಿ ಪ್ರವಿಭಕ್ತಾನಿ ಸ್ವಭಾವ ಪ್ರಭವೈಃ ಗುಣೈಃ -- ಓ ಅರಿಗಳ ಉರಿಯೇ, ಸ್ವಭಾವದಿಂದುಂಟಾದ ಗುಣಗಳಿಗೆ\nಅನುಗುಣವಾಗಿ ಬ್ರಾಹ್ಮಣ, ಕ್ಷತ್ರಿಯ, ವೈಶ್ಯ ಮತ್ತು ಶೂದ್ರರ ಕರ್ಮಗಳೂ ಬೇರೆಬೇರೆಯಾಗಿವೆ.\n\nಜೀವಸ್ವಭಾವಕ್ಕನುಗುಣವಾಗಿ ಮೋಕ್ಷಯೋಗ್ಯವಾದ ಮಾನವನಲ್ಲಿ ನಾಲ್ಕು ವಿಧದ ವರ್ಣಗಳಿವೆ.\nಸ್ವಭಾವಕ್ಕನುಗುಣವಾಗಿ ಪ್ರತಿಯೊಬ್ಬನ ನಡೆ-ನುಡಿ, ಆಚಾರ-ವಿಚಾರ. ಸ್ವಭಾವ ಭೇದದಿಂದಾಗಿ ಗುಣ-ಕರ್ಮ\nಭೇದ. ಇದು ಪೂರ್ಣವಾಗಿ ಜೀವ ಸ್ವಭಾವಕ್ಕೆ ಸಂಬಂಧಪಟ್ಟ ವಿಚಾರವಾಗಿರುವುದರಿಂದ ಇದಕ್ಕೂ ಜಾತಿಗೂ\nಯಾವ ಸಂಬಂಧವೂ ಇಲ್ಲ. ಜಾತಿ ದೇಹಕ್ಕೆ ಸಂಬಂಧಪಟ್ಟದ್ದು, ವರ್ಣ ಜೀವಸ್ವರೂಪಕ್ಕೆ ಸಂಬಂಧಪಟ್ಟದ್ದು.\n[ಚಾತುರ್ವರ್ಣ್ಯದ ಬಗ್ಗೆ ಹೆಚ್ಚಿನ ವಿವರಣೆಯನ್ನು ಅಧ್ಯಾಯ ೦೪-ಶ್ಲೋಕ-೧೩ ರಲ್ಲಿ ವಿವರಿಸಲಾಗಿದೆ]. ಈ ನಾಲ್ಕು\nವರ್ಣದವರ ಸಹಜ ಕರ್ಮದ ವಿವರಣೆಯನ್ನು ಕೃಷ್ಣ ಮುಂದಿನ ಶ್ಲೋಕಗಳಲ್ಲಿ ವಿವರಿಸಿದ್ದಾನೆ.\n",
  "18.42": "ಶಮಃ ದಮಃ ತಪಃ ಶೌಚಂ ಕ್ಷಾಂತಿ ಆರ್ಜವಮ್‌ ಏವ ಚ |\n\nಜ್ಞಾನಂ ವಿಜ್ಞಾನಮ್‌ ಆಸ್ತಿಕ್ಯಂ ಬ್ರಹ್ಮಕರ್ಮ ಸ್ವಭಾವಜಮ್‌ -- ಭಗವಂತನಲ್ಲಿ ನಿಷ್ಠೆ, ಇಂದ್ರಿಯಗಳಲ್ಲಿ ಹಿಡಿತ,\nಉಪವಾಸಾದಿ ನೇಮಗಳು, ನೈರ್ಮಲ್ಯ, ಅಪಕಾರಿಯನ್ನೂ ಮನ್ನಿಸುವ ಸೈರಣೆ, ನೇರ ನಡೆ-ನುಡಿ, ತಿಳಿವು,\nಆಳವಾದ ಸಂಶೋಧನಾ ದೃಷ್ಟಿ ಮತ್ತು ಆಸ್ತಿಕತೆ- ಇವು ಬ್ರಾಹ್ಮಣ ಸ್ವಭಾವದ ಸಹಜ ಕರ್ಮಗಳು.\n\nಜೀವ ಸ್ವಭಾವ “ಬ್ರಾಹ್ಮಣ' ವಾಗಿದ್ದರೆ ಅವರ ಸಹಜ ಕರ್ಮಗಳು ಹೇಗಿರುತ್ತವೆ ಎನ್ನುವುದನ್ನು ಕೃಷ್ಣ ಈ\nಶ್ಲೋಕದಲ್ಲಿ ವಿವರಿಸಿದ್ದಾನೆ. ಈ ವರ್ಣದ ಸ್ವಭಾವಗಳು ಹೀಗಿವೆ:\n\n(೧)ಶಮಃ : ಮನಸ್ಸು ಭಗವಂತನಲ್ಲಿ ನೆಲೆಗೊಂಡಿರುವುದು.\n\n(೨)ದಮಃ : ಇಂದ್ರಿಯಗಳ ಹತೋಟಿ.\n\n(೩)ತಪಃ : ಮಾನಸಿಕವಾಗಿ ವಿಷಯವನ್ನು ಆಳವಾಗಿ ಚಿಂತನೆ ಮಾಡುವುದು, ಮನಸ್ಸು ಒಳ್ಳೆಯದನ್ನು\nಯೋಚಿಸುವುದಕ್ಕೆ ಪೂರಕವಾಗಿ ವೃತಾನುಷ್ಠಾನ, ನಿರಂತರ ಶಾಸ್ತ್ರ ಚಿಂತನೆ.\n\n(೪)ಶೌಚಮ್‌ : ಮನಸ್ಸಿನ ಶುದ್ಧತೆ ಮತ್ತು ಅದಕ್ಕೆ ಪೂರಕವಾಗಿ ಬಾಹ್ಯ ಶುದ್ದಿ.\n\n(೫)ಕ್ಷಾಂತಿ : ತಪ್ಪು ಮಾಡಿದವರನ್ನೂ ಕ್ಷಮಿಸುವ, ಕೋಪಿಸಿಕೊಳ್ಳದ ಮನಸ್ಸು.\n\n(೬)ಆರ್ಜವ : ಸ್ವಚ್ಛ ನಿರಾಳ ಮನಸ್ಸು, ನೇರ ನಡೆ-ನುಡಿ.\n\n(೭)ಜ್ಞಾನ : ಭಗವದ್‌ ವಿಷಯಕವಾದ ಜ್ಞಾನ.\n\n(ಲ)ವಿಜ್ಞಾನ : ಭಗವಂತನ ಬಗ್ಗೆ ಆಳವಾದ ಅರಿವು, ಭಗವಂತನ ಗುಣಗಳ ವಿಶಿಷ್ಠ ಜ್ಞಾನ.\n\n(೯)ಆಸ್ತಿಕ್ಯ : ಪೂರ್ಣವಾಗಿ ಭಗವಂತನ ಅಸ್ತಿತ್ವದಲ್ಲಿ ಭರವಸೆ ಪಡೆದು ಮುಂದೆ ಸಾಗುವುದು.\n\nಈ ಎಲ್ಲಾ ಗುಣಗಳು ಎಲ್ಲಾ ವರ್ಣದವರಲ್ಲೂ ಇರಬೇಕು. ಆದರೆ ಹೆಚ್ಚಿನ ಪ್ರಮಾಣದಲ್ಲಿರುವುದು ಬ್ರಾಹ್ಮಣ\nವರ್ಣದವರಲ್ಲಿ. ಇವುಗಳಲ್ಲಿ ಒಂದು ಗುಣದ ಪ್ರಮಾಣ ಕಡಿಮೆ ಇದ್ದರೂ ಆತ ಬ್ರಾಹ್ಮಣನೆನಿಸುವುದಿಲ್ಲ. ಒಂದು\nವೇಳೆ ಕ್ಷತ್ರಿಯರಲ್ಲಿ ಈ ಗುಣಗಳ ಪ್ರಮಾಣ ಬ್ರಾಹ್ಮಣರಿಗಿಂತ ಹೆಚ್ಚಾಗಿ ಕಂಡುಬಂದರೆ ಆತ ರಾಜರ್ಷಿ\nಎನಿಸುತ್ತಾನೆ. (ಉದಾಹರಣೆಗೆ ಜನಕ ಮಹಾರಾಜ)\n",
  "18.43": "ಶೌರ್ಯಂ ತೇಜಐಃ ಧೃತಿಃ ದಾಕ್ಷ್ಯಮ್‌ ಯುದ್ಧೇ ಚ ಅಪಿ ಅಪಲಾಯನಮ್‌ |\nದಾನಮ್‌ ಈಶ್ವರ ಭಾವಃ ಚ ಕ್ಷಾತ್ರಮ್‌ ಕರ್ಮ ಸ್ವಭಾವಜಮ್‌ -- ಕೆಚ್ಚು, ಕಸುವು, ಗಟ್ಟಿತನ, ಕೌಶಲ,\nಕಾಳಗದಲ್ಲಿ ಬೆನ್ನು ತೋರಿಸದಿರುವುದು, ಕೊಡುಗೈತನ ಮತ್ತು ಒಡೆತನ ಇವು ಕ್ಷತ್ರಿಯ ಸ್ವಭಾವದ ಸಹಜ\nಕರ್ಮಗಳು.\n\nಕ್ಷತ್ರಿಯನಾದವನ ಸಹಜ ಕರ್ಮಗಳನ್ನು ಇಲ್ಲಿ ಕೃಷ್ಣ ವಿವರಿಸಿದ್ದಾನೆ.\n\n(೧) ಶೌರ್ಯಮ್‌ : ಎದುರಾಳಿಗಳನ್ನು ಬಗ್ಗುಬಡಿಯುವ ಶಕ್ತಿ.\n\n(೨) ತೇಜಸ್ಸು : ಎದುರಾಳಿಗಳು ನೋಡಿದಾಕ್ಷಣ ತಲೆ ತಗ್ಗಿಸುವ ತೇಜಸ್ಸು.\n\n(೩) ಧೃತಿ : ಪ್ರಾಣಾಪಾಯ ಬಂದಾಗಲೂ ಎದೆಗೆಡದೆ ಮುನ್ನುಗ್ಗುವ ಸಾಹಸ ಪ್ರವೃತ್ತಿ\n\n(೪) ದಕ್ಷತೆ: ಶತ್ರುಗಳನ್ನು ಮಣಿಸುವ ತಂತ್ರಗಾರಿಕೆ-ಚಾತುರ್ಯ.\n\n(೫) ಯುದ್ಧೇ ಚ ಅಪಿ ಅಪಲಾಯನಮ್‌ : ಯುದ್ಧ ಭೂಮಿಯಲ್ಲಿ ಬೆನ್ನು ಹಾಕದೆ, ಪಲಾಯನ ಮಾಡದೆ\nಹೋರಾಡುವ ಧೀರತನ.\n\n(೬) ದಾನಮ್‌: ದಾನ ಧರ್ಮ ಮಾಡುವುದು.\n\nಈ ಮೇಲಿನ ಆರು ಗುಣಗಳು ಕ್ಷತ್ರಿಯನಲ್ಲಿ ಹೆಚ್ಚಿನ ಪ್ರಮಾಣದಲ್ಲಿರುತ್ತದೆ. ಇತರ ವರ್ಣದವರಲ್ಲಿ ಇದು ಕಡಿಮೆ\nಪ್ರಮಾಣದಲ್ಲಿರುತ್ತದೆ. ಇದಲ್ಲದೆ ಕ್ಷತ್ರಿಯರಿಗೇ ಮೀಸಲಾದ ಒಂದು ವಿಶೇಷ ಗುಣ (೭) ಈಶ್ವರ ಭಾವಃ :\nಅಪರಾಧಿಗೆ ಸೂಕ್ತ ಶಿಕ್ಷೆ ಕೊಡುವ ಅಧಿಕಾರ. ಬೇರೆ ವರ್ಣದವರಿಗೆ ಈ ಅಧಿಕಾರವಿಲ್ಲ.",
  "18.44": "ಕೃಷಿ ಗೋರಕ್ಷ್ಯವಾಣಿಜ್ಯಂ ವೈ ಶ್ಯಕರ್ಮ ಸ್ವಭಾವಜಮ್‌ ।\nಪರಿಚರ್ಯಾತ್ಮಕಂ ಕರ್ಮ ಶೂದ್ರಸ್ಯ ಅಪಿ ಸ್ವಭಾವಜಮ್‌ -- ಬೇಸಾಯ, ಆಕಳು ಸಾಕಣೆ ಮತ್ತು ವ್ಯಾಪಾರ\nವೈಶ್ಯರ ಸ್ವಭಾವಸಹಜವಾದ ಕರ್ಮ. ಸೇವಾರೂಪವಾದ ಕಾಯಕ ಶೂದ್ರ ಸ್ವಭಾವಕ್ಕೆ ಸಹಜವಾದದ್ದು.\n\nವೈಶ್ಯರ ಸ್ವಭಾವಸಹಜ ಕಾಯಕ ಕೃಷಿ, ಗೋರಕ್ಷಣೆಹೈನುಗಾರಿಕೆ) ಮತ್ತು ವಾಣಿಜ್ಯ. ಭೀಷ್ಮಾಚಾರ್ಯರು\nಧರ್ಮರಾಯನಿಗೆ ರಾಜಧರ್ಮ ಉಪದೇಶ ಮಾಡುತ್ತಾ “ಯಾವ ದೇಶದಲ್ಲಿ ಕೃಷಿಕರು ಮತ್ತು\nವಾಣಿಜ್ಯೋದ್ಯಮಿಗಳು ಕರಭಾರ ತಡೆಯಲಾಗದೆ ಬೇರೆ ದೇಶಕ್ಕೆ ಹೊರಟು ಹೋಗುತ್ತಾರೋ- ಆ ದೇಶ\n\nಉದ್ಧಾರವಾಗದು” ಎಂದಿದ್ದಾರೆ. ಕೃಷಿ, ವಾಣಿಜ್ಯ ಮತ್ತು ಹೈನುಗಾರಿಕೆ ದೇಶದ ಬೆನ್ನೆ ಲುಬು. ಈ ಕಾಯಕ ವೈಶ್ಯರ\nಸ್ವಭಾವಸಹಜವಾದ ಕರ್ಮ.\n\nಶೂದ್ರರಲ್ಲಿ ಇನ್ನೊಬ್ಬರ ಸೇವೆ ಮಾಡುವ ಸೇವಾ ಗುಣ ಮಹತ್ವವಾಗಿರುತ್ತದೆ. ಈ ಗುಣ ಇಲ್ಲದವ ಮನುಷ್ಯನೇ\nಅಲ್ಲ. ಯಾರೂ ಏಕವರ್ಣದವನಲ್ಲ. ಎಲ್ಲರಲ್ಲೂ ಎಲ್ಲಾ ಸ್ವಭಾವವಿರುತ್ತದೆ. ಯಾವ ಸ್ವಭಾವ ನಮ್ಮಲ್ಲಿ\nಹೆಚ್ಚಾಗಿದೆಯೋ) ನಾವು ಆ ವರ್ಣಕ್ಕೆ ಸೇರುತ್ತೇವೆ. ಶೂದ್ರ ಸ್ವಭಾವ ಎಷ್ಟು ಮುಖ್ಯ ಎಂದರೆ ಈ\nಸ್ವಭಾವ ಇಲ್ಲದೆ ಬೇರೆ ಸ್ವಭಾವಕ್ಕೆ ಬೆಲೆ ಇಲ್ಲ. ಯಾವಾಗಲೂ ನಾವು ಮಾಡುವ ಕರ್ಮವನ್ನು ಸೇವಾ\nಮನೋವೃತ್ತಿಯಿಂದ ಮಾಡಬೇಕು. ಉದಾಹರಣೆಗೆ: ಬ್ರಾಹ್ಮಣನಾದವನು ಸಮಾಜ ಸೇವೆಯ ಭಾವನೆಯಿಂದ\nಜ್ಞಾನದಾನ ಮಾಡಬೇಕು. ಇಲ್ಲದಿದ್ದರೆ ಅದು ಜ್ಞಾನದಾನವೆನಿಸುವುದಿಲ್ಲ.\n\nವರ್ಣದ ಬಗ್ಗೆ ಕೃಷ್ಣ ಬಹಳ ರೋಚಕವಾದ ವಿವರಣೆಯನ್ನು ಕೊಟ್ಟ. ಸಮಾಜದಲ್ಲಿ ಮತ್ತು ಕೆಲವು ಪ್ರಾಚೀನ\nಗ್ರಂಥಗಳಲ್ಲಿ ವರ್ಣವನ್ನು ಜಾತಿ ಎನ್ನುವ ಶಬ್ದದಿಂದ ಮತ್ತು ಜಾತಿಯನ್ನು ವರ್ಣ ಎನ್ನುವ ಶಬ್ದದಿಂದ\nಬಳಸಿರುವುದನ್ನು ಕಾಣುತ್ತೇವೆ. ಇಂತಹ ಸಂದರ್ಭದಲ್ಲಿ ನಾವು ಗೊಂದಲ ಮಾಡಿಕೊಳ್ಳದೆ, ಅಲ್ಲಲ್ಲಿ ಯಾವ\nಅರ್ಥದಲ್ಲಿ ಹೇಳಲಾಗಿದೆ ಎನ್ನುವುದನ್ನು ತಿಳಿದು, ಅದನ್ನು ಅರ್ಥ ಮಾಡಿಕೊಳ್ಳಬೇಕಾಗುತ್ತದೆ. ಉದಾಹರಣೆಗೆ\n“ವರ್ಣ ಪದ್ಧತಿಯನ್ನು ನನ್ನ ಆಡಳಿತದಲ್ಲಿ ನಾನು ಹೇಗೆ ಪಾಲಿಸಬೇಕು” ಎಂದು ಪ್ರಶ್ನೆ ಮಾಡಿದ\nಧರ್ಮರಾಯನಿಗೆ ಭೀಷ್ಮಾಚಾರ್ಯರು ಹೇಳುತ್ತಾರೆ: “ವರ್ಣ ವಿಭಾಗವೇ ಇಲ್ಲ, ಎಲ್ಲರೂ ದೇವರ ಮಕ್ಕಳು,\nರಾಜನಾದವನಿಗೆ ವರ್ಣಭೇದ ಮಾಡುವ ಅಧಿಕಾರವಿಲ್ಲ” ಎಂದು. ಇಲ್ಲಿ ವರ್ಣ ಎನ್ನು ವುದು ಜಾತಿ ಎನ್ನುವ\nಅರ್ಥದಲ್ಲಿ ಬಳಕೆಯಾಗಿದೆ.\n\nಸಾಮಾನ್ಯವಾಗಿ ಸಮಾಜದಲ್ಲಿ ತಂದೆ/ತಾಯಿಯ ಸ್ವಭಾವ ಯಾವುದಿರುತ್ತದೋ ಅದೇ ಸ್ವಭಾವವನ್ನು ಮಕ್ಕಳು\nಅನುಸರಿಸುತ್ತಾರೆ. ಉದಾಹರಣೆಗೆ: ಒಬ್ಬ ಬ್ರಾಹ್ಮಣನ ಮಗ, ಅವನಿಗೆ ಬ್ರಾಹ್ಮಣ ಸ್ವಭಾವವನ್ನು\nಅನುಸರಿಸುವುದು ಸುಲಭವಾಗುತ್ತದೆ. ಆತ ಅದನ್ನೆ ೀ ಅನುಸರಿಸಿಕೊಂಡು ಬೆಳೆಯುತ್ತಾನೆ. ಹೀಗಾದಾಗ\nನಿಜವಾದ ವರ್ಣವನ್ನು ಗುರುತಿಸುವುದು ಕಷ್ಟವಾಗುತ್ತದೆ. ಹೀಗೆ ವರ್ಣವನ್ನು ಗುರುತಿಸಲು ಕಷ್ಟವಾದಾಗ ಬಂದ\nಪದ್ಧತಿ ಜಾತಿಪದ್ಧತಿ. ಜಾತಿ ಬೇರೆ ವರ್ಣ ಬೇರೆ ಎನ್ನುವುದಕ್ಕೆ ಉತ್ತಮ ಉದಾಹರಣೆ- ಒಬ್ಬ ಬೆಸ್ತರ ಹುಡುಗಿಯಲ್ಲಿ\nಹುಟ್ಟಿದ ವೇದವ್ಯಾಸರು. ಅವರು ಮಹಾಬ್ರಾಹ್ಮಣ ಎನ್ನುವುದನ್ನು ಪ್ರಪಂಚವೇ ಒಪ್ಪಿದೆ.\n\nಇಂದು ಸಮಾಜದಲ್ಲಿ ಜೀವ ಸ್ವಭಾವವನ್ನು ಗುರುತಿಸಿ ಅದಕ್ಕನುಗುಣವಾದ ಕರ್ಮವನ್ನು ಮಾಡುವ ಪದ್ಧತಿ\nಇಲ್ಲವಾಗಿದೆ. ಇದಕ್ಕೆ ವ್ಯತಿರಿಕ್ತವಾಗಿ ತಂದೆ-ತಾಯಿ ತಮ್ಮ ಇಷ್ಟವನ್ನು ತಮ್ಮ ಮಕ್ಕಳ ಮೇಲೆ ಹೇರುತ್ತಿದ್ದಾರೆ.\nಇದು ತೀರಾ ಅವೈಜ್ಞಾನಿಕ ಪದ್ಧತಿ. ಮಕ್ಕಳಲ್ಲಿ ಹುದುಗಿರುವ ನಿಜವಾದ ಪ್ರತಿಭೆಯನ್ನು ಗುರುತಿಸದೆ, ತಾವು\nಹೇಳಿದ ವಿಷಯವನ್ನು ಮಕ್ಕಳು ಕಲಿಯಬೇಕು ಎನ್ನುವುದು ವರ್ಣಪದ್ಧತಿಗೆ ವಿರುದ್ಧವಾದ ಸಂಪ್ರದಾಯ.\nಅವರವರ ಜೀವ ಸ್ವಭಾವ ಏನೋ ಅದಕ್ಕನುಗುಣವಾಗಿ ಅವರು ಕಲಿಯಬೇಕು. ಆಗ ಅವರು ಆ ವಿಷಯದಲ್ಲಿ\nಪರಿಣತರಾಗುತ್ತಾರೆ ಮತ್ತು ಸಮಾಜಕ್ಕೆ ಅವರಿಂದ ಉಪಯೋಗವಾಗುತ್ತದೆ.\n",
  "18.45": "ಸ್ವೇ ಸ್ಟೇ ಕರ್ಮಣಿ ಅಭಿರತಃ ಸಂಸಿದ್ಧಿಂ ಲಭತೇ ನರಃ ।\n\nಸ್ವಕರ್ಮನಿರತಃ ಸಿದ್ಧಿಂ ಯಥಾ ವಿಂದತಿ ತತ್‌ ಶೃಣು -- ತನ್ನತನ್ನ ಸಹಜ ಕರ್ಮದಲ್ಲಿ ನಿರತನಾದ ಮನುಷ್ಯ\nಸಿ ನ್ಹಿಯನ್ನು ಪಡೆಯುತ್ತಾನೆ. ತನ್ನ ದಾದ ಕರ್ಮದಲ್ಲಿ ತೊಡಗಿದವನು ಹೇಗೆ ಸಿದ್ಧಿ ಪಡೆಯುತ್ತಾನೆ ಆ ಬಗೆಯನ್ನು\nಕೇಳು.\n\nಅವರವರ ಸ್ವಭಾವಕ್ಕೆ ಅನುಗುಣವಾದ ಕರ್ಮವನ್ನು ಕೃಷ್ಣ 'ಸ್ವಕರ್ಮ' ಎಂದು ಕರೆದಿದ್ದಾನೆ. 'ನಿನ್ನ ಕರ್ಮ ನೀನು\nಮಾಡು' ಎಂದರೆ ನಿನ್ನ ಸ್ವಭಾವಕ್ಕೆ ಒಗ್ಗುವ ಕರ್ಮವನ್ನು ನೀನು ಮಾಡು ಎಂದರ್ಥ. ಪ್ರಾಮಾಣಿಕತೆ ಮತ್ತು\nಸ್ವಕರ್ಮನಿಷ್ಠೆಗಿಂತ ದೊಡ್ಡ ಧರ್ಮ ಇನ್ನೊಂದಿಲ್ಲ. ತನ್ನ ಸ್ವಭಾವಕ್ಕೆ ಸಹಜವಾದ ಕರ್ಮವನ್ನು ಭಗವದರ್ಪಣಾ\nಬುದ್ಧಿಯಿಂದ ಮಾಡುತ್ತಾ ಪ್ರಾಮಾಣಿಕವಾಗಿ ಬದುಕುವುದೇ ಎಲ್ಲಕ್ಕಿಂತ ಶ್ರೇಷ್ಠ ಧರ್ಮ.\n\nನಮ್ಮಲ್ಲಿ ಕೆಲವರು ಕೇಳಬಹುದು: “ಯಾವ ಕೆಲಸವಾದರೇನು, ಯಾವುದರಿಂದ ಹೆಚ್ಚು ಹಣ ಸಂಪಾದನೆ\nಸಾಧ್ಯವೋ ಆ ಕೆಲಸವನ್ನು ಮಾಡುವುದರಲ್ಲಿ ತಪ್ಪೇನು” ಎಂದು. ಇಲ್ಲಿ ಕೃಷ್ಣ ಅದು ತಪ್ಪು ಎಂದಿದ್ದಾನೆ.\nಯಾವುದೋ ಒಂದು ಕೆಲಸ ಮಾಡುವುದು ಬದುಕಲ್ಲ, ಅದು ಯಾತನೆ. ನಿನ್ನನಿನ್ನ ಸ್ವಭಾವಸಹಜವಾದ\nಕರ್ಮದಲ್ಲಿ ನೀನು ಬದುಕಿದರೆ ಅದು ಬದುಕು. ಅದೇ ಮೋಕ್ಷ ಮಾರ್ಗ. ನಿನ್ನ ಸ್ವಭಾವಕ್ಕೆ ತಕ್ಕಂತೆ ನಿನ್ನ ಶಿಕ್ಷಣ;\nನಿನ್ನ ಶಿಕ್ಷಣಕ್ಕೆ ತಕ್ಕಂತೆ ನಿನ್ನ ಕರ್ಮ. ಹೀಗೆ ಮಾಡಿದಾಗ ಕರ್ಮದಲ್ಲಿ ಅಭಿರತಿ(ಸಂಪೂರ್ಣ ತೃಪ್ತಿ ಮತ್ತು\nಸಂತೋಷ) ಇರುತ್ತದೆ. ಈ ರೀತಿ ಖುಷಿಯಿಂದ ಭಗವದರ್ಪಣೆಯಾಗಿ ಕರ್ಮ ಮಾಡಿದಾಗ, ಬದುಕಿನ ಕೊನೆಯ\nಸಿದ್ಧಿಯಾದ ಮೋಕ್ಷವನ್ನು ಪಡೆಯಬಹುದು. ಸ್ವಭಾವ ಸಹಜವಾದ ಕರ್ಮದಿಂದ ಹೇಗೆ ಸಿದ್ಧಿಯಾಗುತ್ತದೆ\nಎನ್ನುವುದನ್ನು ಕೃಷ್ಣ ಮುಂದಿನ ಶ್ಲೋಕಗಳಲ್ಲಿ ವಿವರಿಸಿದ್ದಾನೆ.\n",
  "18.46": "ಯತಃ ಪ್ರವೃತ್ತಿಃ ರ್ಭೂತಾನಾಂ ಯೇನ ಸರ್ವಮ್‌ ಇದಂ ತತಮ್‌ ।\n\nಸ್ವಕರ್ಮಣಾ ತಮ್‌ ಅಭ್ಯರ್ಚ್ಯ ಸಿದ್ಧಿಂ ವಿಂದತಿ ಮಾನವಃ -- ಯಾರಿಂದ ಜೀವಿಗಳ ಚಟುವಟಿಕೆಯೋ, ಯಾರು ಈ\nಎಲ್ಲವನ್ನು ತುಂಬಿನಿಂತಿರುವನೋ ಅಂತಹ ಭಗವಂತನನ್ನು ಮನುಷ್ಯ ಸ್ವಭಾವಸಹಜವಾದ ಕರ್ಮದಿಂದ\nಆರಾಧಿಸಿ ಸಿದ್ಧಿ ಪಡೆಯುತ್ತಾನೆ.\n\nನಮ್ಮ ಸ್ವಭಾವ ಸಹಜ ಕರ್ಮವನ್ನು ಭಗವಂತನ ಅಭ್ಯರ್ಚನೆಯಾಗಿ ಮಾಡಿದಾಗ ಅದು ಅಧ್ಯಾತ್ಮವಾಗುತ್ತದೆ.\nಇದಕ್ಕಿಂತ ಮಹತ್ತಾದ ಪೂಜೆ ಇನ್ನೊಂದಿಲ್ಲ. ಇಲ್ಲಿ ಅರ್ಚನೆ ಎಂದರೆ ಪುರೋಹಿತರ ಮುಖೇನ ದೇವಸ್ಥಾನದಲ್ಲಿ\nಮಾಡುವ ಅರ್ಚನೆ ಅಲ್ಲ. ಇದು ಇಂದ್ರಿಯ ನಿಗ್ರಹ, ಶಮಃ, ದಮಃ ಎಲ್ಲವೂ ಸೇರಿ ಸ್ವಯಂ ಮಾಡತಕ್ಕ ಅರ್ಚನೆ.\nಆದ್ದರಿಂದ ನಾವು ಮಾಡುವ ಸ್ವಭಾವ ಸಹಜ ಕರ್ಮದಲ್ಲಿ ನಮ್ಮ ಇಂದ್ರಿಯ ನಿಗ್ರಹ ಸೇರಿದೆ, ಭಗವನ್ನಿಷ್ಠೆ ಸೇರಿದೆ,\nಭಗವದರ್ಪಣಾ ಬುದ್ಧಿ ಸೇರಿದೆ. ಇವೆಲ್ಲವೂ ಸೇರಿ ನಾವು ಮಾಡತಕ್ಕ ಪ್ರತಿಯೊಂದು ಸ್ವಕರ್ಮ/ಸಹಜಕರ್ಮ\nಭಗವಂತನ ಪೂಜೆಯಾಗುತ್ತದೆ. ಈ ರೀತಿ ಬದುಕಿದಾಗ ನಮ್ಮ ಇಡೀ ಬದುಕು ದೇವರ ಪೂಜೆಯಾಗುತ್ತದೆ.\nನಮಗೆ ಇಚ್ಛೆ ಮತ್ತು ಪ್ರವೃತ್ತಿಯನ್ನು ಕೊಟ್ಟ ಭಗವಂತನಿಗೆ ನಮ್ಮ ಕರ್ಮವನ್ನು ಅರ್ಪಿಸಿದಾಗ ನಮ್ಮ ಕರ್ಮವೇ\nಒಂದು ಅರ್ಚನೆಯಾಗುತ್ತದೆ.\n",
  "18.47": "ಶ್ರೇಯಾನ್‌ ಸ್ವಧರ್ಮಃ ವಿಗುಣಃ ಪರಧರ್ಮಾತ್‌ ಸು ಅನುಷ್ಠಿತಾತ್‌ |\nಸ್ವಭಾವ ನಿಯತಂ ಕರ್ಮ ಕುರ್ವನ್‌ ನ ಆಪ್ನೋತಿ ಕಿಲ್ಬಿಷಮ್‌ -- ಚೆನ್ನಾಗಿ ಆಚರಿಸಿದ ಪರಧರ್ಮಕ್ಕಿಂತ\nಆಚರಣೆಯಲ್ಲಿ ಕೊರತೆಯಿದ್ದರೂ ತನ್ನ ಸಹಜಧರ್ಮ ಮಿಗಿಲು. ತನ್ನ ಸ್ವಭಾವಕ್ಕೆ ತಕ್ಕುದಾದ ಕರ್ಮ ಮಾಡಿದರೆ\n\nಪಾಪ ತಟ್ಟುವುದಿಲ್ಲ.\n\nನಮ್ಮ ಸ್ವಭಾವಕ್ಕೆ ಸಹಜವಾದ ಸ್ವಧರ್ಮ ಮಾಡುವುದರಿಂದ, ಆ ಕರ್ಮದಲ್ಲಿ ದೋಷವಿದ್ದರೂ ಕೂಡಾ ಅದರಿಂದ\nಪಾಪ ತಟ್ಟುವುದಿಲ್ಲ. ಇದನ್ನು ಬಿಟ್ಟು ಪರಧರ್ಮ ಮಾಡುವುದು ಯುಕ್ತವಲ್ಲ. ವೇದವ್ಯಾಸರು ಯುದ್ಧಾನಂತರ\nತಾನು ಸಿಂಹಾಸನವೇರಲಾರೆ, ನನಗೇನೂ ಬೇಡ, ನಾನು ಕಾಡಿಗೆ ಹೋಗುತ್ತೇನೆ ಎಂದು ಕುಳಿತ\nಧರ್ಮರಾಯನಿಗೆ- “ನೀನು ನಿನ್ನ ಸಹಜ ಧರ್ಮವನ್ನು ಬಿಟ್ಟು ಕಾಡಿಗೆ ಹೋಗುವುದು ಎಷ್ಟು ಅಸಂಗತವೋ, ಅಷ್ಟೇ\nಅಸಂಗತ ನಾನು ತಪಸ್ಸನ್ನು ಬಿಟ್ಟು ಬಂದು ರಾಜ್ಯಭಾರ ಮಾಡುವುದು” ಎಂದು ಬುದ್ಧಿವಾದ ಹೇಳುತ್ತಾರೆ.\nಇದರಿಂದ ನಾವು ತಿಳಿಯಬೇಕಾದದ್ದು ಏನೆಂದರೆ -ನಾವು ಪರಧರ್ಮ ಮಾಡುವುದಕ್ಕಿಂತ-ದೋಷವಿದ್ದರೂ ಸರಿ,\nನಮ್ಮ ಸಹಜ ಕರ್ಮ ಮಾಡುವುದೇ ಅತ್ಯಂತ ಶ್ರೇಷ್ಠ ಧರ್ಮ.\n",
  "18.48": "ಸಹಜಂ ಕರ್ಮ ಕೌಂತೇಯ ಸದೋಷಮ್‌ ಅಪಿ ನ ತ್ಯಜೇತ್‌ |\nಸರ್ವಾರಂಭಾಃ ಹಿ ದೋಷೇಣ ಧೂಮೇನ ಅಗ್ನಿಃ ಇವ ಆವೃತಾಃ ೨. ಕೌಂತೇಯಾ, ಸಹಜವಾದ ಕರ್ಮವನ್ನು\nದೋಷವಿದ್ದರೂ ಬಿಡಬಾರದು. ಎಲ್ಲಾ ಕರ್ಮಗಳಲ್ಲು ದೋಷವಿದ್ದೇ ಇದೆ. ಬೆಂಕಿಯಿದ್ದಲ್ಲಿ ಹೊಗೆ ಇರುವಂತೆ.\n\nನಾವು ನಮ್ಮ ಸ್ವಭಾವಕ್ಕೆ ಮತ್ತು ಪರಿಸ್ಥಿತಿಗೆ ಸಹಜವಾದ ಕರ್ಮದಲ್ಲಿ ಎಷ್ಟೇ ದೋಷವಿದ್ದರೂ ಸಹ ಆ\nಕರ್ಮವನ್ನು ಬಿಡಬಾರದು. ಇಲ್ಲಿ ಪಾಂಡವರ ಸಹಜ ಧರ್ಮ ಅನ್ಯಾಯದ ವಿರುದ್ಧ ಹೋರಾಡುವುದು. ಹೀಗೆ\nಹೋರಾಡುವಾಗ ಸಾವು ನೋವು ಉಂಟಾಗಬಹುದು. ಆದರೆ ಅದು ಪಾಪವಲ್ಲ. ಈ ಪ್ರಪಂಚದಲ್ಲಿ ದೋಷವಿಲ್ಲದ\nಒಂದೂ ಕರ್ಮವಿಲ್ಲ. ಬೆಂಕಿ ಇದ್ದಲ್ಲಿ ಹೊಗೆ ಇದ್ದೇ ಇರುತ್ತದೆ. ಕರ್ಮದಲ್ಲಿ ಹಿಂಸೆ ಇರಬಹುದು, ಆದರೆ ಅದು ಸಹಜ\nಧರ್ಮವಾದಾಗ ಅದನ್ನು ಕೈಬಿಡಲಾಗದು. ಸಹಜ ಧರ್ಮದಲ್ಲಿ ಹಿಂಸೆ ಅನಿವಾರ್ಯವಾದಾಗ ಅದರ ಬಗ್ಗೆ\nತಲೆಕೆಡಿಸಿಕೊಳ್ಳಬಾರದು. ನಮ್ಮ ಪಾಲಿಗೆ ಒದಗಿ ಬರುವ ಕರ್ಮವನ್ನು ಭಗವದರ್ಪಣಾ ಬುದ್ಧಿಯಿಂದ\nನಿಷ್ಕಾಮನಾಗಿ ಮಾಡುವುದು ಧರ್ಮ. ಇದರಿಂದ ಪಾಪ ಅಂಟದು.\n\nಕೇವಲ ಸ್ವಭಾವದಂತೆ ನಡೆದುಕೊಂಡಮಾತ್ರಕ್ಕೆ ಮುಕ್ತಿ ಸಿಗುವುದಿಲ್ಲ. ಅದರ ಹಿಂದೆ ಕೆಲವು ಸಾಧನೆಗಳು\nಬೇಕಾಗುತ್ತದೆ. ಕೆಲವು ಅನುಸಂಧಾನಗಳು ಬೇಕಾಗುತ್ತವೆ. ಅದರ ವಿವರಣೆಯನ್ನು ಕೃಷ್ಣ ಮುಂದಿನ ಶ್ಲೋಕಗಳಲ್ಲಿ\nವಿವರಿಸಿದ್ದಾನೆ.\n",
  "18.49": "ಅಸಕ್ತಬುದ್ಧಿಃ ಸರ್ವತ್ರ ಜಿತಾತ್ಮಾ ವಿಗತಸ್ಪೃಹಃ ।\n\nನೈಷ್ಯರ್ಮ್ಯಸಿದ್ಧಿಂ ಪರಮಾಂ ಸಂನ್ಯಾಸೇನ ಅಧಿಗಚ್ಛತಿ -ಎಲ್ಲೂ ಬುದ್ಧಿಯನ್ನು ಅಂಟಿಸಿಕೊಳ್ಳದೆ , ಬಗೆಯನ್ನು\nಗೆದ್ದು, ಬಯಕೆ ತೊರೆದವನು ಇಂತಹ 'ಸಂನ್ಯಾಸ'ದಿಂದ ಮೋಕ್ಷಪ್ರದವಾದ ಹಿರಿಯ ಯೋಗ ಸಿದ್ಧಿಯನ್ನು [ಅನಿಷ್ಟ\nಕರ್ಮಗಳ ನಾಶವೆಂಬ ಸಿದ್ಧಿಯನ್ನು] ಪಡೆಯುತ್ತಾನೆ.\n\nಮೋಕ್ಷಸಾಧನವಾಗಿರತಕ್ಕಂತಹ ಸಿದ್ಧಿಯನ್ನು [ಪಾಪಕರ್ಮಗಳು ಇಲ್ಲದ ಸ್ಥಿತಿಯನ್ನು ] ತಲುಪಲು ಕೇವಲ\nಸ್ವಕರ್ಮದಲ್ಲಿ ತೊಡಗಿದರೆ ಸಾಲದು, ಬದಲಿಗೆ ನಾವು ನಮ್ಮ ಮನಸ್ಸನ್ನು ನಿಯಂತ್ರಿಸಿ, ಯಾವುದೇ ಫಲಾಪೇಕ್ಷೆ\nಇಲ್ಲದೆ, ನನ್ನಿಂದಾಯ್ತು ಎನ್ನುವ ಅಹಂಕಾರವನ್ನು ಬಿಟ್ಟು, ಭಗವದರ್ಪಣಾ ಭಾವದಿಂದ ಕರ್ಮವನ್ನು\nಮಾಡಬೇಕು. ಅಹಂಕಾರ ಅಧ್ಯಾತ್ಮದ ದೊಡ್ಡ ಶತ್ರು. ಇದರ ಎಚ್ಚರ ನಮಗಿರಬೇಕು. ಒಟ್ಟಿನಲ್ಲಿ ಹೇಳಬೇಕೆಂದರೆ\nಸರ್ವತ್ರ. “ನನ್ನಿಂದಾಯಿತು' ಎನ್ನುವ ಅಹಂಕಾರವನ್ನು ಬಿಟ್ಟು, ಮನಸ್ಸನ್ನು ಗೆದ್ದು, ಬುದ್ಧಿಯಿಂದ\nಫಲಕಾಮನೆಯನ್ನು ತೊಡೆದುಹಾಕಿ, ಕಾಮನೆಗಳ ನ್ಯಾಸ ಮಾಡಿ, ಎಲ್ಲವನ್ನು ಭಗವಂತನಲ್ಲಿ ಅರ್ಪಿಸಿ ಸ್ವಕರ್ಮ\nಮಾಡಿದರೆ- ಮೋಕ್ಷವನ್ನು ಸೇರಲು ಬೇಕಾದ ಸಿದ್ಧಿ ಪ್ರಾಪ್ತವಾಗುತ್ತದೆ.",
  "18.50": "ಏವ ಕೌಂತೇಯ ನಿಷ್ಠಾ ಜ್ಞಾನಸ್ಯ ಯಾ ಪರಾ - ಕೌಂತೇಯಾ, ಯಾವ ಬಗೆಯ ಸಿದ್ಧಿ ಪಡೆದವನು\nನ್ನು [ಶ್ರೀತತ್ವವನ್ನು ]ಸೇರುತ್ತಾನೆ ಆ ಬಗೆಯನ್ನು ಕೇಳು. ಈ ಸಿದ್ಧಿ ತಿಳಿವಿನ ಕೊನೆಯ ಮಜಲು.\n\nಯಾವ ಪಾತಕದಿಂದಲೂ ಕಲುಪಿತವಾಗದ ಜೀವನದ ನಡೇ(ನೈಷ್ಕರ್ಮ್ಯಸಿದ್ಧಿ) ರೂಪಿತವಾದಾಗ ನಮ್ಮ\nಮನಸ್ಸಿನಲ್ಲಿ ಭಗವಂತ ಬಂದು ನೆಲೆಸುತ್ತಾನೆ. ಇದರಿಂದ ತಾಯಿ ಶ್ರಿಲಕ್ಷ್ಮಿಯನ್ನು ಸೇರಿ ಕೊನೆಗೆ ಭಗವಂತನನ್ನು\nಸೇರಲು ಸಾಧ್ಯ. ಯಾವ ರೀತಿ ಬ್ರಹ್ಮತತ್ವವನ್ನು ಸೇರುವುದು ಎನ್ನುವುದನ್ನು ಮುಂದೆ ಕೃಷ್ಣ ಅಡಕವಾಗಿ\nಹೇಳುತ್ತಾನೆ. ನೈಷ್ಕರ್ಮ್ಯಸಿದ್ಧಿ ಎನ್ನುವುದು ಒಬ್ಬ ಮನುಷ್ಯನ ಜ್ಞಾನಸಾಧನೆಯ ಕೊನೇಯ ಮಜಲು. ಈ\nಹಂತವನ್ನು ತಲುಪಬೇಕಾದರೆ ನಾವು ಅಧ್ಯಾತ್ಮದಲ್ಲಿ ಕುಂತಿಯಂತೆ ಛಲವುಳ್ಳ-ಕೌಂತೇಯರಾಗಬೇಕು.",
  "18.51": "ಬುದ್ಧ್ಯಾ ವಿಶುದ್ಧಯಾ ಯುಕ್ತಃ ಧೃತ್ಯಾತ್ಮಾನಂ ನಿಯಮ್ಯ ಚ |\nಶಬ್ದ ಆದೀನ್‌ ವಿಷಯಾನ್‌ ತ್ಯಕ್ತ್ವಾ ರಾಗದ್ವೇಷೌ ವ್ಯುದಸ್ಯ ಚ -- ತಿಳಿಯಾದ ಬುದ್ಧಿಯಿರಬೇಕು. ದಿಟ್ಟತನದಿಂದ\nಬಗೆಯನ್ನು ಬಿಗಿಹಿಡಿಯಬೇಕು. ಶಬ್ದ ಮುಂತಾದ ವಿಷಯಲಾಲಸೆಯನ್ನು ತೊರೆಯಬೇಕು. ಪ್ರೀತಿ-ಹಗೆತನಗಳನ್ನು\nದೂರವಿರಿಸಬೇಕು.\n\nಅಧ್ಯಾತ್ಮ ಸಾಧನೆಯಲ್ಲಿ ನಮ್ಮ ಮನಸ್ಸು ಯಾವತ್ತೂ ಕೂಡಾ ಕೆಟ್ಟದ್ದನ್ನು ಯೋಚಿಸಬಾರದು. ಶುದ್ಧವಾದ ಬುದ್ಧಿ\nನಮ್ಮದಾಗಿರಬೇಕು. ಮನಸ್ಸ ನ್ನು ಬಹಳ ಧೈರ್ಯದಿಂದ ನಿಯಂತ್ರಿಸಿ, ಅಸಾಧಾರಣ ಸಾಹಸದಿಂದ ಎಲ್ಲಾ ಕೆಟ್ಟ\nವಿಚಾರವನ್ನು ಮನಸ್ಸಿನಿಂದ ಹೊಡೆದೋಡಿಸಬೇಕು. ಇಂದ್ರಿಯಗಳು ಮನಸ್ಸನ್ನು ಕದಡುವ ಸಾಧನಗಳು.\nಆದ್ದರಿಂದ ಕೇಳುವ, ನೋಡುವ, ಮುಟ್ಟುವ, ಮೂಸುವ ಮತ್ತು ತಿನ್ನುವ ಚಪಲವನ್ನು ಮೊದಲು ಬಿಡಬೇಕು.\nಮಗುವಿನಂತೆ ರಾಗ-ದ್ವೇಷವಿಲ್ಲದೆ ನಿರ್ಮಲ ಮನಸ್ಸಿನಿಂದಿರಬೇಕು.\n",
  "18.52": "ವಿವಿಕ್ತಸೇವೀ ಲಘ ಆಶೀ ಯತ ವಾಕ್‌ ಕಾಯ ಮಾನಸಃ |\n\nಧ್ಯಾನ ಯೋಗ ಪರಃ ನಿತ್ಯಂ ವೈರಾಗ್ಯಂ ಸಮಪಾಶ್ರಿತಃ ---- ಏಕಾಂತದಲ್ಲಿ ನೆಲೆಸಬೇಕು. ಮಿತವಾಗಿ\nಉಣ್ಣಬೇಕು. ಮಾತು-ಮೈ-ಮನಗಳಲ್ಲಿ ಹಿಡಿತವಿರಬೇಕು. ಧ್ಯಾನಯೋಗದಲ್ಲಿದ್ದು ಅನುದಿನವೂ ವೈರಾಗ್ಯ\nತಳೆಯಬೇಕು.\n\nಹಾಳು ಹರಟೆ ನಡೆಯುವ ಜನಸಂದಣಿಯಲ್ಲಿ ಬೆರೆಯದೆ, ಆದಷ್ಟು ಏಕಾಂತದಲ್ಲಿರುವುದನ್ನು ಅಭ್ಯಾಸ\nಮಾಡಿಕೊಳ್ಳಬೇಕು. ಅಧ್ಯಾತ್ಮ ಸಾಧನೆಯಲ್ಲಿ ಆದಷ್ಟು ಪವಿತ್ರವಾದ ಸ್ಥಳವನ್ನು ಆಯ್ಕೆ ಮಾಡಿಕೊಂಡು ಅಭ್ಯಾಸ\nಮಾಡಬೇಕು. ಅತಿಯಾಗಿ ತಿಂದಾಗ ಮನಸ್ಸು ಕೆಲಸ ಮಾಡುವುದಿಲ್ಲ. ಅದಕ್ಕಾಗಿ ನಿಯತವಾದ ಸಮಯದಲ್ಲಿ\nನಿಯತ ಆಹಾರವನ್ನು ಸೇವನೆ ಮಾಡಬೇಕು. ಮಾತಿನ ಮೇಲೆ ನಿಯಂತ್ರಣ, ದೇಹದ ಚಟುವಟಿಕೆಯ ಮೇಲೆ\nನಿಯಂತ್ರಣ, ಮನಸ್ಸಿನ ಚಿಂತನೆಯಲ್ಲಿ ನಿಯಂತ್ರಣವಿದ್ದು. ಧ್ಯಾನ ಮಾಡಬೇಕು. ಜೀವನದಲ್ಲಿ ಎಲ್ಲವನ್ನು\n\nಪ್ರೀತಿಸುತ್ತಾ ಯಾವುದನ್ನೂ ಅಂಟಿಸಿಕೊಳ್ಳದೇ ಬದುಕಬೇಕು.\n",
  "18.53": "ಅಹಂಕಾರಂ ಬಲಂ ದರ್ಪಂ ಕಾಮಂ ಕ್ರೋಧಂ ಪರಿಗ್ರಹಮ್‌ |\n\nವಿಮುಚ್ಯ ನಿರ್ಮಮಃ ಶಾಂತಃ ಬ್ರಹ್ಮಭೂಯಾಯ ಕಲ್ಪತೇ --ನಾನೆಂಬ ಹಮ್ಮು, ಬಲಾತ್ಕಾರ, ಸೊಕ್ಕು, ಕಾಮ,\nಕೋಪ ಮತ್ತು ಕೈಯೊಡ್ಡುವ ಬುದ್ಧಿ ಇವುಗಳನ್ನು ತೊರೆದು, ಮಮತೆಯಳಿದು ಭಗವಂತನಲ್ಲಿ ಬಗೆಯಿಡಬೇಕು.\nಆಗ ಭಗವಂತನಲ್ಲೇ ಬಗೆ ನೆಲೆಗೊಳ್ಳುತ್ತದೆ.[ಅಂತವನು ಶ್ರೀತತ್ವವನ್ನು ಸೇರುತ್ತಾನೆ]\n\nಭಗವಂತನ ಚಿಂತನೆಗೆ ವಿರುದ್ಧವಾಗಿ 'ನಾನು ಮಾಡಿದೆ' ಅನ್ನುವ ಅಹಂಕಾರ, ಇನ್ನೊಬ್ಬರ ಮೇಲೆ ತಮ್ಮ\nಅಭಿಪ್ರಾಯ ಹೇರುವುದು, ತನ್ನ ಸ್ಥಿತಿಯ ಬಗ್ಗೆ ದರ್ಪ, ಕಾಮ-ಕ್ರೋಧ, ಇನ್ನೊಬ್ಬರ ಮುಂದೆ ಕೈಯೊಡ್ಡುವ ಬುದ್ಧಿ-\nಇವೆಲ್ಲವನ್ನು ತೊರೆದು, ನಾನು-ನನ್ನದು ಎನ್ನುವ ಮಮಕಾರವನ್ನು ಬಿಟ್ಟು, ಭಗವಂತನಲ್ಲಿ ಮನಸ್ಸನ್ನು\nಏಕಾಗ್ರಗೊಳಿಸುವುದರಿಂದ ಬ್ರಹ್ಮತತ್ವವನ್ನು ಸೇರಬಹುದು. [ಮನಸ್ಸು ಭಗವಂತನಲ್ಲಿ ನೆಲೆಗೊಳ್ಳುತ್ತದೆ;\nಚತುರ್ಮುಖನ ಉಪದೇಶ ಪಡೆದು- ತಾಯಿ ಲಕ್ಷ್ಮಿಯನ್ನು ಸೇರುತ್ತಾನೆ].",
  "18.54": "ಬ್ರಹ್ಮಭೂತಃ ಪ್ರಸನ್ನಾತ್ಮಾ ನ ಶೋಚತಿ ನ ಕಾಂಕ್ಷತಿ ।\n\nಸಮಃ ಸರ್ವೇಷು ಭೂತೇಷು ಮತ್‌ ಭಕ್ತಿಂ ಲಭತೇ ಪರಾಮ್‌ - ಭಗವಂತನಲ್ಲೇ ಬಗೆ ನೆಟ್ಟವನು [ಶ್ರೀತತ್ವದಲ್ಲಿ\nನೆಲೆಗೊಂಡವನು] ಬಗೆ ತಿಳಿಗೊಂಡು ಯಾವುದಕ್ಕೂ ದುಃಖಿಸುವುದಿಲ್ಲ; ಯಾವುದನ್ನೂ ಬಯಸುವುದಿಲ್ಲ. ಎಲ್ಲಾ\nಜೀವಿಗಳಲ್ಲೂ ಸಮಭಾವ ಹೊಂದಿ ನನ್ನಲ್ಲಿ ಪರಾಭಕ್ತಿಯನ್ನು ಪಡೆಯುತ್ತಾನೆ.\n\nಭಗವಂತನಲ್ಲಿ ಬಗೆ ನೆಟ್ಟವನಿಗೆ ಯಾವುದೇ ಬೇಕು-ಬೇಡಗಳಿರುವುದಿಲ್ಲ. ಆತನ ಮನಸ್ಸು ಸ್ವಚ್ಛವಾಗಿರುತ್ತದೆ. ಈ\nಸ್ಥಿತಿಯಲ್ಲಿ ಸರ್ವೋತ್ಕೃಷ್ಟ ಭಕ್ತಿ ಬೆಳೆಯುತ್ತದೆ. ಗುಣಪೂರ್ಣನಾದ ಭಗವಂತನನ್ನು ಆತ ಪ್ರಪಂಚದ ಪ್ರತೀ\nವಸ್ತುವಿನಲ್ಲೂ ಕಾಣುತ್ತಾನೆ. ಇದರಿಂದಾಗಿ ಆತನಲ್ಲಿ ಯಾವುದೇ ತಾರತಮ್ಯ, ದ್ವೇಷ ಇರುವುದಿಲ್ಲ.",
  "18.55": "ಭಕ್ತ್ಯಾ ಮಾಮಭಿಜಾನಾತಿ ಯಾವಾನ್‌ ಯಶ್ಚಾಸ್ಮಿ ತತ್ತ್ವತಃ |\nತತೋ ಮಾಂ ತತ್ತ್ವತೋ ಜ್ಞಾತ್ವಾ ವಿಶತೇ ತದನಂತರಮ್‌ ॥\n\nಭಕ್ತ್ಯಾ ಮಾಮ್‌ ಅಭಿಜಾನಾತಿ ಯಾವಾನ್‌ ಯಃ ಚ ಅಸ್ಮಿ ತತ್ತ್ವತಃ |\nತತಃ ಮಾಮ್‌ ತತ್ತ್ವತಃ ಜ್ಞಾತ್ವಾ ವಿಶತೇ ತತ್‌ ಅನಂತರಮ್‌ -ಭಕ್ತಿಯಿಂದ “ನಾನು' ಏನು ಎಂತು\nಎನ್ನುವುದನ್ನು ಸರಿಯಾಗಿ ಅರಿಯಬಲ್ಲವನಾಗುತ್ತಾನೆ. ಅಂತಹ ಪರಾಭಕ್ತಿಯಿಂದ ನನ್ನನ್ನು ಸರಿಯಾಗಿ ಅರಿತ\nಅನಂತರ ನನ್ನನ್ನೇ ಸೇರುತ್ತಾನೆ.\n\nಇಂತಹ ಭಕ್ತಿಯ ಉತ್ಕೃಷ್ಟ ಸ್ಥಿತಿಯಲ್ಲಿರುವವನಿಗೆ ಯಾವುದೇ ತಪ್ಪು ತಿಳುವಳಿಕೆ ಇರುವುದಿಲ್ಲ. ಲಕ್ಷ್ಮಿಯ\nಸನ್ನಿಧಾನದಿಂದ ಭಗವಂತ ಅಂದರೇನು, ಅವನ ಮಹಿಮೆ ಏನು, ಅವನ ಶಕ್ತಿ ಏನು, ಅವನ ಅನಂತ ಗುಣಗಳ\nಹರವು ಏನು- ಎನ್ನುವುದು ಯಥಾವತ್ತಾಗಿ ಜೀವಯೋಗ್ಯತೆಯ ಪೂರ್ಣ ಪ್ರಮಾಣದಲ್ಲಿ ಅರಿಯುತ್ತಾನೆ. \"ಈ ರೀತಿ\nತತ್ತ್ವತಃ ಭಗವಂತನನ್ನು ಯಥಾವತ್ತಾಗಿ ತಿಳಿದ ಮೇಲೆ ಅತ್ಯಂತ ಪರಿಶುದ್ಧ ಜ್ಞಾನ ಮತ್ತು ಭಕ್ತಿಯಿಂದ ನನ್ನನ್ನು\n\nಬಂದು ಸೇರುತ್ತಾನೆ” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.\n",
  "18.56": "ಸರ್ವ ಕರ್ಮಾಣಿ ಅಪಿ ಸದಾ ಕುರ್ವಾಣಃ ಮತ್‌ ವ್ಯಪಾಶ್ರಯಃ ।\nಮತ್‌ ಪ್ರಸಾದಾತ್‌ ಅವಾಪ್ನೋತಿ ಶಾಶ್ವತಮ್‌ ಪದಮ್‌ ಅವ್ಯಯಮ್‌ - 'ನಾನೇ' ಸರ್ವಸ್ವ ಎಂದು ತಿಳಿದು ಎಲ್ಲಾ\nಕರ್ಮಗಳನ್ನು ನಿರಂತರ ಮಾಡುತ್ತಿರುವವನು ನನ್ನ ಹಸಾದದಿಂದ, ಅಳಿವಿರದ ಬದಲಾಗದ ತಾಣವನ್ನು\n\nಸೇರುತ್ತಾನೆ.\n\nಭಗವಂತನೇ ಸರ್ವಸ್ವ ಎಂದು ತಿಳಿದು; ಯಾವುದೇ ಕರ್ಮ ಮಾಡಿದರೂ ಆ ಕರ್ಮದ ಗುರಿ\nಭಗವಂತನನ್ನಾಗಿರಿಸಿಕೊಂಡು; ಪೂರ್ಣ ಭಗವದರ್ಪಣಾ ಬುದ್ಧಿಯಿಂದ ಕರ್ಮ ಮಾಡುವವರು, ಭಗವಂತನ\nಅನುಗ್ರಹದಿಂದ ಎಂದೂ ಏರುಪೇರಿಲ್ಲದ ಮೋಕ್ಷವನ್ನು ಸೇರುತ್ತಾರೆ.",
  "18.57": "ಚೇತಸಾ ಸರ್ವಕರ್ಮಾಣಿ ಮಯಿ ಸಂನ್ಯಸ್ಯ ಮತ್‌ ಪರಃ ।\nಬುದ್ಧಿಯೋಗಮುಪಾಶ್ರಿತ್ಯ ಮಚ್ಚಿತ್ತಃ ಸತತಂ ಭವ 1೫೭॥\n\nಚೇತಸಾ ಸರ್ವಕರ್ಮಾಣಿ ಮಯಿ ಸಂನ್ಯಸ್ಯ ಮತ್‌ ಪರಃ ।\n\nಬುದ್ಧಿಯೋಗಮ್‌ ಉಪಾಶ್ರಿತ್ಯ ಮತ್‌ ಚಿತ್ತಃ ಸತತಮ್‌ ಭವ - ಒಳಬಗೆಯಿಂದ ಎಲ್ಲಾ ಕರ್ಮಗಳನ್ನು\nನನಗೊಪ್ಪಿಸಿ, ನನ್ನನ್ನೇ ಪರತತ್ವವೆಂದು ತಿಳಿದು, ಜ್ಞಾನಯೋಗದ ದಾರಿ ಹಿಡಿದು ನಿರಂತರ ನನ್ನಲ್ಲೇ\nಒಳಬಗೆಯನ್ನಿಡು.\n\nಇಲ್ಲಿ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ನನ್ನನ್ನು ತಿಳಿದು, ಎಲ್ಲಾ ಕರ್ಮವನ್ನು ನನ್ನಲ್ಲಿ ಅರ್ಪಿಸಿ, ಜ್ಞಾನಯೋಗದಿಂದ ಮನಸ್ಸನ್ನು\nನಿರಂತರ ನನ್ನಲ್ಲಿರಿಸು” ಎಂದು . ಇಲ್ಲಿ ನಾವು ಮಾಡುವ ಎಲ್ಲಾ ಕರ್ಮವನ್ನು ಭಗವಂತನಿಗೆ ಅರ್ಪಿಸಿ\nಮಾಡಬೇಕು ಎನ್ನು ವುದು ಬಹಳ ಮುಖ್ಯವಾದ ವಿಷಯ. ಇಂದು ಈ ರೀತಿಯ ಕರ್ಮ ಸಾಧನೆ ಇಲ್ಲವಾಗಿದೆ.\nಇದಕ್ಕೆ ಮೂಲ ಕಾರಣ ಅಜ್ಞಾನ. ನಾವು ಪೂಜೆ ಮಾಡುವುದು ಯಾವುದೋ ಫಲದ ಅಪೇಕ್ಷೆಯಿಂದ. ಕೆಲವೊಮ್ಮೆ\nಜ್ಯೋತಿಷಿಗಳು ಯಾವುದೋ ಗ್ರಹ ದೋಷವಿದೆ ಎಂದು ಹೇಳುತ್ತಾರೆ. ಉದಾಹರಣೆಗೆ: ಕುಜದೋಷ.\nಸಾಮಾನ್ಯವಾಗಿ ಜ್ಯೋತಿಷಿಗಳು ಕುಜದೋಷ ಎಂದು ಹೇಳಿದಾಗ ನಮಗೆ ಮೊದಲು ಕಾಣುವುದು “ಈ ಗ್ರಹ\nನಮಗೆ ತೊಂದರೆ ಕೊಡುತ್ತಿದೆ' ಎಂದು. ವಸ್ತುತಃ ಕುಜದೋಷ ಎಂದರೆ ಕುಜನ ದೋಷವಲ್ಲ. ಅದು ನಮ್ಮ\nದೋಷ. ನಮ್ಮ ಪ್ರಾರಾಬ್ಧಕರ್ಮ. ಅದನ್ನು ಈ ಗ್ರಹ ಸೂಚಿಸುತ್ತದೆ ಅಷ್ಟೆ. ಅದನ್ನು ನಾವು ತಪ್ಪಾಗಿ ಕುಜನೇ ನನ್ನ\nಬೆನ್ನ ಹಿಂದೆ ಬಿದ್ದಿದ್ದಾನೆ ಎಂದು ತಿಳಿದುಕೊಳ್ಳುತ್ತೇವೆ. ಗ್ರಹಗಳಿರುವುದು ನಮಗೆ ಕಾಟ ಕೊಡಲಿಕ್ಕಾಗಿ ಅಲ್ಲ.\nಅವರು ಎಂದೂ ಕಾಟ ಕೊಡುವುದಿಲ್ಲ. ಬದಲಿಗೆ ನಮಗೆ ನಮ್ಮ ಪ್ರರಾಬ್ಧದಿಂದ ಬರತಕ್ಕ ಕಾಟವನ್ನು ಅವರು\nಸೂಚಿಸುತ್ತಾರೆ. ನಮಗೆ ಕಷ್ಟಬರುವ ಸಾಧ್ಯತೆಯನ್ನು ನಮಗೆ ಮುಂದಾಗಿ ತಿಳಿಸಿ, ನಾವು ಆ ಅನಿಷ್ಟವನ್ನು\nಎದುರಿಸಲು ಮಾನಸಿಕ ಸಿದ್ಧತೆ ನಡೆಸುವಂತೆ ಮಾಡುವುದು ಗ್ರಹಗಳ ಕರ್ತವ್ಯ. ಹೀಗೆ ಪ್ರಾರಾಬ್ಧಕರ್ಮ ಇದೆ\nಎಂದು ಗೊತ್ತಾದಾಗ, ಆ ಸಮಸ್ಯೆಯನ್ನು ಎದುರಿಸಿ, ಸಾಧನಾ ಮಾರ್ಗದಲ್ಲಿ ಮುಂದೆ ಸಾಗುವುದಕ್ಕೆ\nಭಗವಂತನಲ್ಲಿ ಮೊರೆ ಹೋಗುವುದು ಪ್ರಾಯಶ್ಚಿತ್ತ ಪೂಜೆಯೇ ಹೊರತು-ಇದು ಗ್ರಹಗಳಿಗೆ ಕೊಡುವ ಲಂಚವಲ್ಲ.\nಉದಾಹರಣೆಗೆ ನವಗ್ರಹ ಪೂಜೆ. ನಮ್ಮ ಪ್ರಾರಾಬ್ಧಕರ್ಮವನ್ನು ಗ್ರಹಗಳು ಸೂಚಿಸಿರುವುದರಿಂದ, ಆ ಗ್ರಹಗಳ\nಅಂತರ್ಯಾಮಿಯಾಗಿರುವ ಭಗವಂತನನ್ನು ಪ್ರಾರ್ಥಿಸುವುದು ನವಗ್ರಹಪೂಜೆ.\n\nನಾರಾಯಣನ ಭಕ್ತನನ್ನೂ ಪ್ರಾರಾಬ್ಧಕರ್ಮ ಬಿಡುವುದಿಲ್ಲ. ನಮ್ಮ ಪ್ರಾರಾಬ್ಧಕ್ಕೆ ತಕ್ಕಂತೆ ನಾವು ನಮ್ಮ\nಗ್ರಹಚಾರವನ್ನು ಅನುಭವಿಸಲೇಬೇಕು. ಜ್ಞಾನಿಗಳಿಗೂ ಕೂಡಾ ಕಷ್ಟ ಬರುತ್ತದೆ. ಆ ದುಃಖವನ್ನು ಎದುರಿಸುವ\nಸಾಮರ್ಥ್ಯ ನಮ್ಮಲ್ಲಿಲ್ಲದಾಗ ಭಗವಂತನನ್ನು ಪ್ರಾರ್ಥಿಸುವುದು ತಪ್ಪಲ್ಲ. ಇಲ್ಲಿ ಒಂದು ಬಹಳ ಮುಖ್ಯ ವಿಷಯ\nಏನೆಂದರೆ ಫಲಾಪೇಕ್ಷೆ ಇಲ್ಲದೆ ಪರಮಾತ್ಮನಲ್ಲಿ ಪ್ರಾರ್ಥನೆ. “ನಾನು ನನ್ನ ಹಿಂದಿನ ಜನ್ಮದಲ್ಲಿ ಮಾಡಿದ ಕರ್ಮದ\nಫಲವಾಗಿ ಇಂದು ಈ ಅನಿಷ್ಟವನ್ನು ಪಡೆದಿದ್ದೇನೆ. ನನ್ನ ಮುಂದಿರುವ ಈ ಗ್ರಹಚಾರವನ್ನು ನೀನು ಗ್ರಹಗಳ\nಅಂತರ್ಯಾಮಿಯಾಗಿ ನಿಂತು ನನಗೆ ತೋರಿಸಿದ್ದೀಯ. ನಿನಗೆ ನನ್ನ ಕೋಟಿ-ಕೋಟಿ ನಮನ. ನನಗರಿವಿಲ್ಲದೆ\nನಾನು ಮಾಡಿದ ತಪ್ಪನ್ನು ಮನ್ನಿಸಿ, ನಾನು ಈ ಅನಿಷ್ಟವನ್ನು ಎದುರಿಸಿ ಜ್ಞಾನ ಮಾರ್ಗದಲ್ಲಿ ಮುನ್ನೆಡೆದು ನಿನ್ನನ್ನು\nಸೇರಲು ನನಗೆ ದಾರಿ ತೋರಿಸು; ನನ್ನೊಳಗಿರುವ ನೀನು ನಿನ್ನ ಪೂಜೆಯನ್ನು ನನ್ನನ್ನು ಮಾಧ್ಯಮವಾಗಿ ಬಳಸಿ\nಮಾಡಿಸಿಕೋ; ನಾನು ನಿನ್ನಲ್ಲಿ ಶರಣಾಗಿದ್ದೇನೆ” ಎನ್ನುವ ಅನುಸಂಧಾನ ಈ ಪೂಜೆಯ ಹಿಂದಿರಬೇಕು. ಹೀಗೆ\n\nಭಗವಂತ ಸರ್ವಶ್ರೇಷ್ಠ ಎನ್ನುವ ಎಚ್ಚರದಿಂದ, ಎಲ್ಲಾ ದೇವತೆಗಳ ಆರಾಧನೆ ಮಾಡುವಾಗಲೂ ಸಹ- ಅವರ\nಅಂತರ್ಯಾಮಿಯಾಗಿರತಕ್ಕಂತಹ ಭಗವಂತನನ್ನು ತಿಳಿದು, ಕರ್ಮವನ್ನು ಮಾನಸಿಕವಾಗಿ ಭಗವಂತನಲ್ಲಿ\nಅರ್ಪಿಸಬೇಕು. ಇದು ನಿಜವಾಗಿ ಮಾಡಬೇಕಾದ ಕರ್ಮದ ವಿಧಾನ.\n\nಒಟ್ಟಿನಲ್ಲಿ ಹೇಳಬೇಕೆಂದರೆ: ನಾವು ನಮ್ಮ ಮನಸ್ಸು ಬೇರೆಕಡೆ ಹೋಗದಂತೆ ತಡೆದು ಅದನ್ನು ಭಗವಂತನಲ್ಲಿ\nನೆಲೆಗೊಳಿಸಬೇಕು; ನಾವು ಮಾಡುವ ಎಲ್ಲಾ ಕರ್ಮಗಳೂ ಭಗವಂತನ ಪೂಜಾರೂಪವಾಗಿದ್ದು, ಅದನ್ನು\nಭಗವಂತ ನಮ್ಮ ಕೈಯಿಂದ ಮಾಡಿಸುತ್ತಿದ್ದಾನೆ ಎನ್ನುವ ಎಚ್ಚರ ನಮ್ಮ ಮನಸ್ಸಿನಲ್ಲಿ ನೆಲೆಗೊಳ್ಳಬೇಕು. ನಮ್ಮ\nಅನುಷ್ಠಾನ, ಅನುಸಂಧಾನ ಆನಂದಮಯವಾಗಿರಬೇಕು. ಅಲ್ಲಿ ಯಾವುದೇ ಒತ್ತಡ, ಭಯ, ಫಲಾಪೇಕ್ಷೆ\nಇರಕೂಡಾದು.\n",
  "18.58": "ಮತ್‌ ಚಿತ್ತಃ ಸರ್ವದುರ್ಗಾಣಿ ಮತ್‌ ಪ್ರಸಾದಾತ್‌ ತರಿಷ್ಯಸಿ |\nಅಥ ಚೇತ್‌ ತ್ವಮ್‌ ಅಹಂಕಾರಾತ್‌ ನ ಶ್ರೋಷ್ಯಸಿ ವಿನಂಕ್ಷ್ಯಸಿ -ನನ್ನಲ್ಲೇ ಒಳಬಗೆಯಿಟ್ಟಾಗ, ನನ್ನ ಹಸಾದದಿಂದ\nಎಲ್ಲಾ ಕೋಟಲೆಗಳನ್ನು ದಾಟುವೆ. ಒಂದೊಮ್ಮೆ ಹೆಮ್ಮೆಯಿಂದ ಕಿವಿಗೊಡದಿದ್ದರೆ ಕೆಟ್ಟುಹೋಗುವೆ.\n\nಮನಸ್ಸನ್ನು ಭಗವಂತನತ್ತ ಹರಿಸಿ, ಬುದ್ಧಿಯಲ್ಲಿ ಭಗವಂತನನ್ನು ನೆಟ್ಟು, ಚಿತ್ತದಲ್ಲಿ ಭಗವಂತನನ್ನು ಸ್ಥಿರಗೊಳಿಸಿ,\nಸುಪ್ತಪ್ರಜ್ಞೆಯಲ್ಲಿ ಕೂಡಾ ಭಗವಂತನ ಸ್ಮರಣೆ ಶಾಶ್ವತಗೊಳಿಸಿದಾಗ, ನಮ್ಮ ಎಲ್ಲಾ ಕ್ರಿಯೆಗಳೂ ಭಗವಂತನ\nಪೂಜೆಯಾಗುತ್ತದೆ. ಇದರಿಂದ ನಮ್ಮ ಎಲ್ಲಾ ವ್ಯವಹಾರದಲ್ಲೂ ಪೂರ್ಣ ಪ್ರಾಮಾಣಿಕತೆ ವ್ಯಕ್ತವಾಗುತ್ತದೆ ಹಾಗೂ\nಜೀವನದಲ್ಲಿ ಬರುವ ದುರ್ಗಮ ಸ್ಥಿತಿ, ಕಷ್ಟ, ಕಾರ್ಪಣ್ಯಗಳನ್ನು ಎದುರಿಸುವ ಕ್ಷಮತೆ ಬರುತ್ತದೆ. ಹೀಗೆ ಜ್ಞಾನಿ ತನ್ನ\nಜೀವನ ಪಯಣದಲ್ಲಿ ಅನಿವಾರ್ಯವಾಗಿ ಬರುವ ಎಲ್ಲಾ ಆಪತ್ತುಗಳನ್ನು ನಿರಾಯಾಸವಾಗಿ ದಾಟಿ\nಮುನ್ನೆಡೆಯುತ್ತಾನೆ. ಈ ರೀತಿ ಬದುಕಿದಾಗ ಭಗವಂತ ನಮ್ಮ ಜೀವನದಲ್ಲಿ ಬರುವ ಸರ್ವ ಅನಿಷ್ಟಗಳಿಂದಲೂ\nನಮ್ಮನ್ನು ರಕ್ಷಿಸುತ್ತಾನೆ. ಆತನ ರಕ್ಷಾಕವಚ ಸದಾ ನಮ್ಮನ್ನು ಸುತ್ತುವರಿದಿರುತ್ತದೆ. ಇದರಿಂದ ಜೀವನದಲ್ಲಿ\nಬರುವ ಎಲ್ಲಾ ಆಪತ್ತುಗಳಿಂದ ನಾವು ಪಾರಾಗುತ್ತೇವೆ. ಇದನ್ನು ಬಿಟ್ಟು ವೇದಾಂತ ಕೇವಲ ಬೊಗಳೆ, ಅದರಲ್ಲಿ\nನನಗೆ ನಂಬಿಕೆ ಇಲ್ಲ ಎಂದು ಅಹಂಕಾರ ಪಟ್ಟರೆ, ನಮ್ಮ ಕೈಯಾರೆ ನಾವು ನಮ್ಮ ಭವಿಷ್ಯವನ್ನು ಹಾಳು\nಮಾಡಿಕೊಂಡು ವಿನಾಶ ಹೊಂದುತ್ತೇವೆ.",
  "18.59": "ಯತ್‌ ಅಹಂಕಾರಮ್‌ ಆಶ್ರಿತ್ಯ ನ ಯೋತ್ಸ್ಯೇ ಇತಿ ಮನ್ಯಸೇ |\n\nಮಿಥ್ಯಾ ಏಷಃ ವ್ಯವಸಾಯಃ ತೇ ಪ್ರಕೃತಿಃ ತ್ವಾಮ್‌ ನಿಯೋಕ್ಷ್ಯತಿ - ಅಹಂಕಾರದಿಂದ ಬೀಗಿ “ನಾನು\nಹೋರಾಡುವುದಿಲ್ಲ' ಎಂದು ತಿಳಿದಿರುವೆಯಾದರೆ ನಿನ್ನ ಈ ನಿರ್ಧಾರ ಹುಸಿಯಾದದ್ದು. ನಿನ್ನ ಸ್ವಭಾವ\n[ಭಗವಂತನ ಇಚ್ಛೆ] ನಿನ್ನನ್ನು ಹೋರಾಡಿಸುತ್ತದೆ.\n\n'ನಾನು ಯುದ್ಧ ಮಾಡುವುದಿಲ್ಲ' ಎಂದು ಅರ್ಜುನ ರಥದಲ್ಲಿ ಕುಸಿದು ಕುಳಿತದ್ದನ್ನು ನಾವು ಅಧ್ಯಾಯ ಒಂದರಲ್ಲಿ\nನೋಡಿದ್ದೇವೆ. ಇಲ್ಲಿ ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ “ “ನಾನು ಯುದ್ಧ ಮಾಡುವುದಿಲ್ಲ' ಎನ್ನುವುದು ನಿನ್ನ ಅಹಂಕಾರಭರಿತ\nಭ್ರಮೆ. ನೀನು ಏನನ್ನು ಮಾಡುವುದಿಲ್ಲ ಎಂದು ಹೇಳಿರುವೆಯೋ ಅದನ್ನೇ ಮಾಡುತ್ತೀಯ” ಎಂದು. ಏಕೆಂದರೆ\nನಮ್ಮನ್ನು ನಿಯಂತ್ರಣ ಮಾಡುವ ಶಕ್ತಿ ಪ್ರಕೃತಿ. ಇಲ್ಲಿ ನಮ್ಮ ಭೌತಿಕ ತೀರ್ಮಾನ ವ್ಯರ್ಥ. ನಮ್ಮ ಜೀವಸ್ವಭಾವ,\nಅದಕ್ಕನುಗುಣವಾಗಿ ಅನುವಂಶೀಯ ಪ್ರಭಾವ, ಪರಿಸರದ ಪ್ರಭಾವ ಮತ್ತು ಈ ಎಲ್ಲವನ್ನೂ ನಿಯಂತ್ರಿಸುವ\nಭಗವಂತನ ಇಚ್ಛೆಯಂತೆ ಕ್ರಿಯೆ ನಡೆದೇ ನಡೆಯುತ್ತದೆ.\n",
  "18.60": "ಸ್ವಭಾವಜೇನ ಕೌಂತೇಯ ನಿಬದ್ಧಃ ಸ್ವೇನ ಕರ್ಮಣಾ |\n\nಕರ್ತುಂ ನ ಇಚ್ಛಸಿ ಯತ್‌ ಮೋಹಾತ್‌ ಕರಿಷ್ಯಸಿ ಅವಶಃ ಅಪಿ ತತ್‌ - ಕೌಂತೇಯಾ, ಸ್ವಭಾವ ಸಹಜವಾದ ನಿನ್ನ\nಕರ್ಮದಿಂದ ನೀನು ಸುತ್ತುವರಿದಿರುವೆ. ಅಜ್ಞಾನದಿಂದಾಗಿ. ಯಾವುದನ್ನು ಮಾಡಬಾರದು ಎಂದೆಣಿಸಿರುವೆ,\nಅದನ್ನು ನೀನು ನಿನಗರಿವಿಲ್ಲದಂತೆಯೇ[ಭಗವದಿಚ್ಛೆಗೆ ವಶನಾಗಿ] ಮಾಡುವೆ.\n\nನಾವು ಹೀಗೆ ಮಾಡಬೇಕು, ಹಾಗೆ ಮಾಡಬೇಕು. ಎಂದು ಅಹಂಕಾರದಿಂದ ಯೋಚಿಸುವುದು ನಮ್ಮ\nಅಜ್ಞಾನದಿಂದ. ಈ ರೀತಿ ಯಾವ ಯೋಚನೆ ಮಾಡಿದರೂ ಕೊನೆಗೆ ಮಾಡುವುದು ನಮ್ಮ ಜೀವ ಸ್ವಭಾವಕ್ಕೆ\nಅನುಗುಣವಾಗಿಯೇ. ಇದರ ನಿಯಂತ್ರಣ ನಮ್ಮಲ್ಲಿಲ್ಲ. ಅದು ನಮಗರಿವಿಲ್ಲದಂತೆ, ಭಗವಂತನ ಇಚ್ಚೆಯಂತೆ\nನಡೆಯುತ್ತದೆ.",
  "18.61": "ಈಶ್ವರಃ ಸರ್ವಭೂತಾನಾಂ ಹೃತ್‌ ದೇಶೇ ಅರ್ಜುನ ತಿಷ್ಠತಿ ।\n\nಭ್ರಾಮಯನ್‌ ಸರ್ವಭೂತಾನಿ ಯಂತ್ರ ಆರೂಢಾನಿ ಮಾಯಯಾ - ಅರ್ಜುನಾ, ಎಲ್ಲಾ ಜೀವಿಗಳ ಎದೆಯ\nತಾಣದಲ್ಲಿ ಸರ್ವಶಕ್ತನಾದ ಭಗವಂತ ನೆಲೆಸಿದ್ದಾನೆ - ಸುತ್ತುವ ಜಗದ್‌ ಯಂತ್ರದಲ್ಲಿ ಕೂತ ಎಲ್ಲಾ ಜೀವಿಗಳನ್ನೂ\nಪ್ರಕೃತಿಯ ಮಾಯೆಯಿಂದ [ತನ್ನ ಇಚ್ಛೆಯಿಂದ]ತಿರುಗಾಡಿಸುತ್ತಾ.\n\nಎಲ್ಲಾ ಜೀವರ ಹೃತ್ಯಮಲದ ಮಧ್ಯದಲ್ಲಿ ಸರ್ವಶಕ್ತನಾದ ಭಗವಂತ ನೆಲೆಸಿದ್ದಾನೆ. ಈ ಪಿಂಡಾಂಡ ಮತ್ತು\nಬ್ರಹ್ಮಾಂಡ ಎನ್ನುವ ಅದ್ಭುತ ಯಂತ್ರ ನಿರಂತರ ಚಲಿಸುವಂತೆ ಮಾಡುವವ ಆ ಭಗವಂತ. ಆತನೇ ಬ್ರಹ್ಮಾಂಡ\nಮತ್ತು ಪಿಂಡಾಂಡದ ಒಡೆಯ. ಎಲ್ಲರೊಳಗಿದ್ದು ಅವರಿಗೆ ಅನುಭವವನ್ನು ಕೊಟ್ಟು ನಿಯಂತ್ರಿಸುವ ಮಹಾ ಚೈತನ್ಯ\nಆ ಭಗವಂತ. ಸರ್ವ ಕರ್ಮವೂ ಭಗವಂತನ ಮಹಿಮೆಯಿಂದ ಅವನ ಇಚ್ಛೆಯಂತೆ ನಡೆಯುತ್ತದೆ.\n",
  "18.62": "ತಮ್‌ ಏವ ಶರಣಂ ಗಚ್ಛ ಸರ್ವಭಾವೇನ ಭಾರತ ।\nತತ್‌ ಪ್ರಸಾದಾತ್‌ ಪರಾಂ ಶಾಂತಿ ಸ್ಥಾನಂ ಪ್ರಾಪ್ಸ್ಯಸಿ ಶಾಶ್ವತಮ್‌ - ಭಾರತಾ, ಎಲ್ಲಾ ಬಗೆಯಿಂದಲೂ\nಅವನಿಗೇ ಶರಣಾಗು. ಅವನ ಕರುಣೆಯಿಂದ ಹಿರಿದಾದ ಸುಖವನ್ನು , ಅಳಿವಿರದ ತಾಣವನ್ನು ಪಡೆಯುವೆ.\n\nಸರ್ವಸಮರ್ಥನಾದ ಭಗವಂತನಿಗೆ ನಾವು ನಮ್ಮನ್ನು ಅರ್ಪಿಸಿಕೊಳ್ಳಬೇಕು. ನಮ್ಮ ಜೀವನದ ಎಲ್ಲಾ\nಹಂತಗಳಲ್ಲೂ ಭಗವಂತನಲ್ಲಿ ಶರಣಾಗತಿ ಇರಬೇಕು.[ಕೇವಲ ಕಷ್ಟ ಕಾಲದಲ್ಲಿ ಮಾತ್ರವಲ್ಲ]. ನಮ್ಮಲ್ಲಿ\nಸತ್ವಗುಣವನ್ನು ಬೆಳಸಿಕೊಂಡು, ಕತ್ತಲೆಯನ್ನು ದೂರಮಾಡಿ, ಭಗವಂತನಲ್ಲಿ ನಮ್ಮನ್ನು ನಾವು\nಅರ್ಪಿಸಿಕೊಂಡಾಗ-ನಮಗೆ ನಿಜವಾದ ಪೂರ್ಣ ಸತ್ವದ ದರ್ಶನವಾಗುತ್ತದೆ. ಆ ಭಗವಂತ ಕಣ್ಣು ತೆರೆದು\nಅನುಗ್ರಹ ಮಾಡಿದನೆಂದರೆ ನಂತರ ತಿಳಿವು ಬರಲು ಇತರ ಯಾವ ಸಾಧನವೂ ಬೇಡ. ಸತ್ಯ ತನ್ನಷ್ಟಕ್ಕೆ ತಾನು\nತೆರೆದುಕೊಳ್ಳುತ್ತದೆ. ಮತ್ತು ಸರ್ವೋತ್ಕೃಷ್ಟ ಆನಂದ ನಮ್ಮದಾಗುತ್ತದೆ. ಇದರಿಂದ ಜ್ಞಾನಾನಂದದ ತುತ್ತ\nತುದಿಯಾದ ಮೋಕ್ಷವನ್ನು ಸೇರಬಹುದು.\n",
  "18.63": "ಇತಿ ತೇ ಜ್ಞಾನಮ್‌ ಆಖ್ಯಾತಂ ಗುಹ್ಯಾತ್‌ ಗುಹ್ಯತರಂ ಮಯಾ।\nವಿಮೃಶ್ಯ ಏತತ್‌ ಅಶೇಷೇಣ ಯಥಾ ಇಚ್ಛಸಿ ತಥಾ ಕುರು. -- ತುಂಬಾ ಜತನದಿಂದ ಬಚ್ಚಿಡಬೇಕಾದ ಈ\nತಿಳಿವನ್ನು ನಾನು ನಿನ್ನೆದುರು ಬಿಚ್ಚಿಟ್ಟೆ. ಇದನ್ನೆ ಲ್ಲವನ್ನು ಪರಾಂಬರಿಸಿ ಮತ್ತೆ ನಿನಗೆ ತೋಚಿದಂತೆ ಮಾಡು.\n\nಕೃಷ್ಣ ಹದಿನೈದನೇ ಅಧ್ಯಾಯದಲ್ಲಿ ಜ್ಞಾನದ ಉಪಸಂಹಾರ ಮಾಡಿದ್ದ. ಇಲ್ಲಿ ಉಪಾಸನೆಯ ಎಲ್ಲಾ ಅರಿವನ್ನು\nಕೊಟ್ಟ ನಂತರ ಅದರ ಉಪಸಂಹಾರ ಮಾಡುತ್ತಾ ಹೇಳುತ್ತಾನೆ: “ಇದು ಪ್ರಪಂಚದಲ್ಲಿನ ರಹಸ್ಯಗಳಲ್ಲಿ ರಹಸ್ಯ.\nಅಧ್ಯಾತ್ಮದ ಅಂತರಂಗದ ರಹಸ್ಯವನ್ನು ನಿನಗೆ ಹೇಳಿದೆ. ನಾನು ಹೇಳಿರುವ ವಿಚಾರವನ್ನು ಸಮಗ್ರವಾಗಿ\n\nಪರಾಂಬರಿಸಿ ನಿನಗೆ ಮನವರಿಕೆಯಾದಂತೆ ಮಾಡು” ಎಂದು. ಇಲ್ಲಿ 'ನಿನ್ನ ಜೀವಸ್ವರೂಪ, ಆತ್ಮಸಾಕ್ಷೆ ಏನು\nಹೇಳುತ್ತದೋ ಹಾಗೇ ಮಾಡು' ಎಂದು ಅರ್ಜುನನಿಗೆ ಹೇಳುವ ಮೂಲಕ-ನಾವು ಇನ್ನೊ ಬ್ಬರ ಮೇಲೆ ನಮ್ಮ\nಅಭಿಪ್ರಾಯ ಹೇರಬಾರದು ಎನ್ನು ವ ಸಮಾಜನೀತಿಯನ್ನು ಕೃಷ್ಣ ಎತ್ತಿ ತೋರಿಸಿದ್ದಾನೆ.\n",
  "18.64": "ಸರ್ವ ಗುಹ್ಯ ತಮಮ್‌ ಭೂಯಃ ಶೃಣು ಮೇ ಪರಮಂ ವಚಃ ।\nಇಷ್ಟಃ ಅಸಿ ಮೇ ದೃಢಮ್‌ ಇತಿ ತತಃ ವಕ್ಷ್ಯಾಮಿ ತೇ ಹಿತಮ್‌ - ಎಲ್ಲಕ್ಕೆಂತ ಹೆಚ್ಚು ಬಚ್ಚಿಡಬೇಕಾದ ನನ್ನಿ ಹಿರಿಯ\nಮಾತನ್ನು ಇನ್ನೊಮ್ಮೆ ಆಲಿಸು. ನೀನು ನನಗೆ ತುಂಬಾ ಮೆಚ್ಚಿನವನೆಂದು, ಅದಕ್ಕಾಗಿ ನಿನಗೆ ಹಿತ-ವಾದವನ್ನು\nಹೇಳುತ್ತಿದ್ದೇನೆ:\n\nಹಿಂದೆ ಹೇಳಿದ ಸಾಧನೆಯ ಸಾರವನ್ನು, ನಾವು ತಿಳಿದುಕೊಳ್ಳಬೇಕಾದ ವಿಷಯಗಳಲ್ಲಿ ಅತ್ಯಂತ ರಹಸ್ಯವಾದ\nಸಾಧನೆಯ ಗುಟ್ಟನ್ನು ಸಾತ್ವಿಕನಾದ ನಿನಗೆ ಇನ್ನೊಮ್ಮೆ ಹೇಳುತ್ತಿದ್ದೇನೆ; ನನ್ನ ಭಕ್ತನಾದ ನೀನು ಜ್ಞಾನಿ.\nಜ್ಞಾನಿಗಳು ನನಗೆ ಅಚ್ಚುಮೆಚ್ಚು, ಅದಕ್ಕಾಗಿ ಅದನ್ನು ಮತ್ತೊಮ್ಮೆ ಹೇಳುತ್ತಿದ್ದೇನೆ- ಕೇಳು:\n",
  "18.65": "ಮತ್‌ ಮನಾಃ ಭವ ಮತ್‌ ಭಕ್ತಃ ಮತ್‌ ಯಾಜೀ ಮಾಂ ನಮಸ್ಕುರು |\n\nಮಾಮ್‌ ಏವ ಏಷ್ಯಸಿ ಸತ್ಯಂ ತೇ ಪ್ರತಿಜಾನೇ ಪ್ರಿಯಃ ಅಸಿ ಮೇ -- ನನ್ನಲ್ಲೇ ಬಗೆಯಿಡು. ನನ್ನಲ್ಲೇ ಭಕ್ತಿಯಿಡು.\nನನ್ನನ್ನೇ ಪೂಜಿಸು. ನನಗೇ ಪೊಡಮಡು. ಆಗ ನನ್ನನ್ನೇ ಸೇರುವೆ. ನೀನು ನನಗೆ ಮೆಚ್ಚಿನವ. ನಿನ್ನಾಣೆಗೂ ಇದು\nನಿಜ.\n\nಸಾಧನೆಯ ಸಾರವನ್ನು ವಿವರಿಸುತ್ತಾ ಕೃಷ್ಣ ಇಲ್ಲಿ ಹಿಂದೆ. ವಿವರಿಸಿದ ವಿಷಯವನ್ನು, ಸಾಧನೆಯ\nಸಾರಸಂಗ್ರಹವನ್ನು. ಮತ್ತೆ ಉಪಸಂಹಾರ ರೂಪದಲ್ಲಿ ಹೇಳುತ್ತಾನೆ. . ಕೃಷ್ಣ ಹೇಳುತ್ತಾನೆ: “ನನ್ನಲ್ಲೇ\nಮನಸ್ಸನ್ನಿಡು” ಎಂದು. ಸಾಧನೆಯಲ್ಲಿ ನಮ್ಮ ಅನನ್ಯಚಿಂತನೆ. ಕೇವಲ ಭಗವಂತನ ಕುರಿತಾದ\nಏಕಭಕ್ತಿಯಾಗಿರಬೇಕು. ಜ್ಞಾನಪೂರ್ವಕವಾಗಿ ಭಗವಂತ ಸರ್ವೋತ್ತಮ ಎಂದು ಭಗವಂತನನ್ನು ನೆನೆಯಬೇಕು.\nಭಗವಂತನಲ್ಲಿ “ಶುದ್ಧವಾದ ಪ್ರೀತಿ. ಇರಲಿ”. ನಾವು. ಮಾಡುವ ಎಲ್ಲಾ ಕರ್ಮಗಳೂ ಪ್ರೀತಿಪೂರ್ವಕ\nಭಗವದರ್ಪಣೆಯಾಗಿರಬೇಕು. “ಸರ್ವದೇವ ನಮಸ್ಕಾರಃ ಕೇಶವಂ ಪ್ರತಿಗಚ್ಛತಿ” ಎನ್ನುವ ಸತ್ಯವನ್ನು ತಿಳಿದು\nಸರ್ವಾಂತರ್ಯಾಮಿ ಭಗವಂತನನ್ನು ಪೂಜಿಸು. ಈ ರೀತಿ ಎಲ್ಲಾ ಉಪಾಸನೆಯಲ್ಲಿ ಭಗವಂತನನ್ನು ಕಂಡರೆ\n\"ನನ್ನನ್ನೇ ಬಂದು ಸೇರುತ್ತೀಯ ಇದು ನಿನ್ನಾಣೆಗೂ ಸತ್ಯ\" ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ.\n",
  "18.66": "ಸರ್ವಧರ್ಮಾನ್‌ ಪರಿತ್ಯಜ್ಯ ಮಾಮ್‌ ಏಕಮ್‌ ಶರಣಂ ವ್ರಜ |\n\nಅಹಂ ತ್ವಾಮ್‌ ಸರ್ವ ಪಾಪೇಭ್ಯಃ ಮೋಕ್ಷಯಿಷ್ಯಾಮಿ ಮಾ ಶುಚಃ -- ಎಲ್ಲಾ ಬಿನುಗು ಧರ್ಮಗಳನ್ನೂ ಫಲದ\nಹಂಬಲಗಳನ್ನೂ ತೊರೆದು. ನನಗೊಬ್ಬನಿಗೇ ಶರಣಾಗು. ನಾನು ನಿನ್ನನ್ನು ಎಲ್ಲಾ ಪಾಪಗಳಿಂದಲೂ\nಪಾರುಗಾಣಿಸುತ್ತೇನೆ. ಕೊರಗದಿರು.\n\n'ಸರ್ವಧರ್ಮಾನ್‌ ಪರಿತ್ಯಜ್ಯ' ಎಂದರೆ ಎಲ್ಲಾ ಪುಣ್ಯಕರ್ಮಗಳನ್ನು ಮಾಡಿ ಅದರಿಂದ ಫಲಾಪೇಕ್ಷೆಯನ್ನು\nನಿರೀಕ್ಷಿಸದೇ ಇರುವುದು. ನಾವು ಮಾಡುವ ಧರ್ಮಕಾರ್ಯ ವ್ಯಾಪಾರವಾಗಬಾರದು. ಇದಕ್ಕೆ ಒಂದು ಉತ್ತಮ\nದೃಷ್ಟಾಂತ ಧರ್ಮರಾಯ ಮತ್ತು ದ್ರೌಪದಿ ನಡುವಿನ ಸಂಭಾಷಣೆ. ದ್ರೌಪದಿ ಹೇಳುತ್ತಾಳೆ: “ಧರ್ಮೋ ರಕ್ಷತಿ\nರಕ್ಷಿತಃ - ಯಾರು ಧರ್ಮವನ್ನು ರಕ್ಷಿಸುತ್ತಾರೋ ಅವರನ್ನು ಧರ್ಮ ರಕ್ಷಿಸುತ್ತದೆ ಎನ್ನುವುದನ್ನು ಕೇಳಿದ್ದೇನೆ, ಅದು\nನಿನ್ನನ್ನು ಏಕೆ ರಕ್ಷಿಸಲಿಲ್ಲ? ನಾವೇಕೆ ರಾಜ್ಯ ಕಳೆದುಕೊಂಡು ಕಾಡು ಸೇರಬೇಕಾಯ್ತು? ” ಎಂದು. ಅದಕ್ಕೆ\nಧರ್ಮರಾಯ ಕೊಡುವ ಉತ್ತರ ರೋಚಕ. ಆತ ಹೇಳುತ್ತಾನೆ: “ನಾನು ಧರ್ಮದ ವ್ಯಾಪಾರಿ ಅಲ್ಲ; ನಾನು ಧರ್ಮ\nಆಚರಣೆ ಮಾಡುವುದು ನನ್ನ ಆತ್ಮಸಂತೋಷಕ್ಕಾಗಿಯೇ ಹೊರತು ಯಾವುದೋ ಫಲಾಪೇಕ್ಷೆಯಿಂದಲ್ಲ” ಎಂದು.\nಹೀಗೆ ಯಾವುದೇ ಧರ್ಮವಿದ್ದರೂ ಅದು ಕೇವಲ ಭಗವಂತನ ಆರಾಧನೆ. ಅಲ್ಲಿ ಫಲಾಪೇಕ್ಷೆ ಇಲ್ಲ. ಈ ರೀತಿ\nಬದುಕಿದಾಗ ಭಗವಂತ ನಮ್ಮ ಎಲ್ಲಾ ಜನ್ಮಗಳ ಪಾಪಗಳನ್ನು ಸುಟ್ಟುಬಿಡುತ್ತಾನೆ. ಭಗವಂತನಲ್ಲಿ ಪೂರ್ಣ\nಶರಣಾದಾಗ ಭಗವಂತನ ಕೈಯಲ್ಲಿ ನಾವು ಸುರಕ್ಷಿತವಾಗಿ ಧೈರ್ಯದಿಂದಿರಬಹುದು. ಇದು ಗೀತೆಯ\nಉಪದೇಶದಲ್ಲಿ ಕೃಷ್ಣ ನಮಗೆ ಕೊಟ್ಟ ಕೊನೆಯ ಭರವಸೆ. ಇಲ್ಲಿಗೆ ಗೀತೆಯಲ್ಲಿ ಭಗವಂತನ ಉಪದೇಶದ ಭಾಗ\nಮುಗಿಯಿತು. ಈ ಅಧ್ಯಾಯದ ಮುಂದಿನ ಶ್ಲೋಕಗಳಲ್ಲಿ ಗೀತೆಯ ಫಲಶ್ರುತಿಯನ್ನು ಕಾಣಬಹುದು.\n",
  "18.67": "ಇದಂ ತೇ ನ ಅತಪಸ್ಕಾಯ ನ ಅಭಕ್ತಾಯ ಕದಾಚನ |\n\nನಚ ಅಶುಶ್ರೂಷವೇ ವಾಚ್ಯಂ ನಚ ಮಾಂ ಯಃ ಅಭ್ಯಸೂಯತಿ - ಇದನ್ನು ನೇಮದ ನಿಷ್ಠೆ ಇರದವರಿಗೆ\nಹೇಳಬೇಡ. ಭಕ್ತಿ ಇರದವನಿಗೆ ಎಂದೂ ಹೇಳಬೇಡ. ಕೇಳುವಾಸೆ ಇರದವನಿಗೂ ಹೇಳಬೇಡ. ನನ್ನ ಬಗೆಗೆ ಕಿಚ್ಚು\nಪಡುವವನಿಗಂತೂ ಹೇಳಲೇಬೇಡ.\n\nಇಲ್ಲಿ ಕೃಷ್ಣ ಜ್ಞಾನದ ಪರಂಪರೆಯನ್ನು ಹೇಗೆ ರಕ್ಷಿಸಬೇಕು ಎನ್ನುವುದನ್ನು ವಿವರಿಸಿದ್ದಾನೆ. ಯಾರಿಗೆ ಆಳವಾದ\nಚಿಂತನಶೀಲತೆ ಇಲ್ಲವೋ ಅವರಿಗೆ ಇದನ್ನು ಹೇಳಬೇಡ; ಚಿಂತನಶೀಲತೆ ಇದ್ದು ಕೇಳುವ ಆಸಕ್ತಿ ಇಲ್ಲದವರಿಗೆ\nಇದನ್ನು ಹೇಳಬೇಡ; ಆಸಕ್ತಿ ಇದೆ ಆದರೆ ಭಕ್ತಿ/ಪ್ರೀತಿ ಇಲ್ಲ-ಅಂತವರಿಗೆ ಇದನ್ನು ಹೇಳಬೇಡ; ಎಲ್ಲಕ್ಕೆಂತ\nಮಿಗಿಲಾಗಿ ಭಗವಂತನ ಬಗ್ಗೆ ಅಸಹನೆ,ಅಸೂಯೆ, ದ್ವೇಷವುಳ್ಳವರಿಗೆ ಸರ್ವತಾ ಹೇಳಲೇಬೇಡ. ಎಂದೂ\nಅಧ್ಯಾತ್ಮವನ್ನು ಬೀದಿಯ ಸೊತ್ತಾಗಿಸಬೇಡ.\n\nಒಂದು ಕಾಲದಲ್ಲಿ ವೇದಾಂತವನ್ನು ಸಾರ್ವಜನಿಕವಾಗಿ ಬಿಚ್ಚಿಡಬಾರದು, ಅದನ್ನು ರಹಸ್ಯವಾಗಿಡಬೇಕು ಎನ್ನು ವ\nಅಭಿಪ್ರಾಯ ಹೆಚ್ಚಾಗಿ ಬೆಳೆಯಿತು. ಇದರ ಪರಿಣಾಮ ಕಾಲಕ್ರಮೇಣ ಮುಚ್ಚಿಟ್ಟ ಜ್ಞಾನವನ್ನು ತೆರೆಯುವವರೇ\nಇಲ್ಲವಾಯಿತು. ಇಂದು ನಮ್ಮಲ್ಲಿ ಹೆಚ್ಚಿನವರು ಆಧ್ಯಾತ್ಮಿಕ ಗ್ರಂಥಗಳಿಗೆ ಆರತಿ ಮಾಡಿ ಕುಂಕುಮ ಹಚ್ಚಿ\nಮುಚ್ಚಿಡುವವರೇ ಹೆಚ್ಚಾಗಿದ್ದಾರೆ. ಈ ಕಾರಣದಿಂದ ನಾವು ಮುಚ್ಚಿಟ್ಟ ಈ ಅಮೂಲ್ಯ ಜ್ಞಾನವನ್ನು ತೆರೆದು\nಆಸಕ್ತಿವುಳ್ಳವರಿಗೆ ಕೊಡುವ ಕೆಲಸ ಮಾಡಬೇಕಾಗಿದೆ.\n\nಭಗವದ್ಗೀತೆಯ ಈ ಅಮೂಲ್ಯ ಸಂದೇಶದ ಅಧ್ಯಯನ ಮಾಡಿ ಮನನ ಮಾಡುವುದರಿಂದ ಸಿಗುವ ಫಲಶ್ರುತಿ\nಏನು ಎನ್ನುವುದನ್ನು ಕೃಷ್ಣ ಮುಂದಿನ ನಾಲ್ಕು ಶ್ಲೋಕಗಳಲ್ಲಿ ವಿವರಿಸಿದ್ದಾನೆ. ಭಗವದ್ಗೀತೆಯ ನಿಜವಾದ ಫಲ\nಮನುಷ್ಯನ ಪುರುಷಾರ್ಥದಲ್ಲಿ ಕೊನೆಯದಾದ ಮೋಕ್ಷ. ಅಧ್ಯಾತ್ಮ ವಿದ್ಯೆಯನ್ನು ಹೇಳುವ ಸಮಸ್ತ ಶಾಸ್ತ್ರಗಳ ಸಾರ\nಭಗವದ್ಗೀತೆ. ಭಗವಂತನ ಸ್ವರೂಪವನ್ನು ತಿಳಿದು ಭಗವಂತನ ಲೋಕ ಸೇರಲು ಇದೊಂದೇ ಗ್ರಂಥ ಸಾಕು.\nಸಮಸ್ತ ಶಾಸ್ತ್ರಗಳಲ್ಲಿನ ಸಮಸ್ತ ಸಾರವನ್ನು, ಸಮಸ್ತ ರಹಸ್ಯವನ್ನು ನಾವು ಈ ಕೃಷ್ಣಾರ್ಜುನ ಸಂವಾದದಲ್ಲಿ\nಕಾಣಬಹುದು. ಈ ರೀತಿ ಎಲ್ಲಾ ಶಾಸ್ತ್ರಗಳ ಪೂರ್ಣ ಸಾರಸಂಗ್ರಹ ಅಡಕವಾಗಿರುವ ಗ್ರಂಥ ಇನ್ನೊಂದಿಲ್ಲ.\nಇಂತಹ ಗೀತೆಯನ್ನು ನಾವು ಗುರು ಮುಖೇನ ತಿಳಿಯುವುದರಿಂದ; ಮನನ ಮಾಡುವುದರಿಂದ; ಇಲ್ಲಿ ಹೇಳಿರುವ\nಸಾಧನಾ ಉಪಾಯವನ್ನು ಜೀವನದಲ್ಲಿ ಅನುಸರಿಸುವುದರಿಂದ; ನಾವು ತಿಳಿದ ಜ್ಞಾನವನ್ನು ಆಸಕ್ತರಿಗೆ\nತಿಳಿಸುವುದರಿಂದ-ನಾವು ಭಗವಂತನ ಲೋಕವನ್ನು(ಮೋಕ್ಷವನ್ನು) ಸೇರಬಹುದು.\n",
  "18.68": "ಯಃ ಇಮಂ ಪರಮಂ ಗುಹ್ಯಂ ಮತ್‌ ಭಕ್ತೇಷು ಅಭಿಧಾಸ್ಯತಿ ।\nಭಕ್ತಿಂ ಮಯಿ ಪರಾಂ ಕೃತ್ವಾ ಮಾಮ್‌ ಏವ ಏಷ್ಯತಿ ಅಸಂಶಯಃ - ತುಂಬಾ ಗೋಪ್ಯವಾದ ಇದನ್ನು ನನ್ನ ಭಕ್ತರಲ್ಲಿ\nಅರುಹುವವನು ನನ್ನಲ್ಲಿ ಹಿರಿಯ ಭಕ್ತಿಯನ್ನು ಮಾಡಿ ನನ್ನನ್ನೇ ಸೇರುತ್ತಾನೆ; ಸಂಶಯವಿಲ್ಲ.\n\nಯಾರು ಇಂತಹ ಜ್ಞಾನವನ್ನು ಅರಿತು, ಅದನ್ನು 'ನನ್ನಲ್ಲಿ ಶ್ರದ್ಧಾಭಕ್ತಿಯುಳ್ಳ ಸಾಧಕನಿಗೆ' ಕೊಡುತ್ತಾರೋ, ಅವರು\nನಿಶ್ಚಿತವಾಗಿ ನನ್ನನ್ನು ಬಂದು ಸೇರುತ್ತಾರೆ. ಇದರಲ್ಲಿ ಸಂಶಯವಿಲ್ಲ.",
  "18.69": "ನಚ ತಸ್ಮಾತ್‌ ಮನುಷ್ಯೇಷು ಕಶ್ಚಿತ್‌ ಮೇ ಪ್ರಿಯಕೃತ್‌ ತಮಃ ।\nಭವಿತಾ ನಚ ಮೇ ತಸ್ಮಾತ್‌ ಅನ್ಯಃ ಪ್ರಿಯತರಃ ಭುವಿ - ಮನುಷ್ಯರಲ್ಲಿ ಅವನಿಗಿಂತ ಹೆಚ್ಚು ಮೆಚ್ಚಿನವನು ನನಗೆ\nಇನ್ನೊಬ್ಬ ನಿಲ್ಲ. ಅವನಿಗಿಂತ ಹೆಚ್ಚು ಮೆಚ್ಚಿನ ಇನ್ನೊಬ್ಬ ಭೂಮಿಯಲ್ಲಿ ಮುಂದೆ ಹುಟ್ಟಲಾರ.\n\n“ಗೀತೆಯನ್ನು ತಿಳಿದು ಅದನ್ನು ಭಕ್ತ ಜನಾಂಗಕ್ಕೆ ತಲುಪಿಸುವ ಶ್ರೇಷ್ಠ ಕಾರ್ಯ ಮಾಡುವವರು ಮನುಷ್ಯರಲ್ಲಿ\nನನಗೆ ಅತ್ಯಂತ ಮೆಚ್ಚಿನವರು. ಇವರಿಗಿಂತ ಹೆಚ್ಚು ಇಷ್ಟವಾದದ್ದನ್ನು ಮಾಡುವ ಮಾನವ ಈ ಭೂಮಿಯ ಮೇಲೆ\nಇಲ್ಲ” ಎನ್ನುತ್ತಾನೆ ಕೃಷ್ಣ. ಭಗವಂತನಿಗೆ ಜ್ಞಾನಿಗಳು ಅಚ್ಚುಮೆಚ್ಚು. ಅವರಿಗಿಂತಲೂ ಅಚ್ಚುಮೆಚ್ಚು ತಾವು\nಜ್ಞಾನಿಗಳಾಗಿ, ಆ ಜ್ಞಾನದ ಸವಿಯನ್ನು ಸಮಾಜಕ್ಕೆ ಕೊಡುವವರು. “ಇವರು ಭೂಮಿಯಲ್ಲಿ ನನಗೆ ಇಷ್ಟವಾದದ್ದನ್ನು\nಮಾಡುವವರಲ್ಲಿ ಸರ್ವಶ್ರೇಷ್ಠರು” ಎಂದಿದ್ದಾನೆ ಕೃಷ್ಣ.",
  "18.70": "ಅಧ್ಯೇಷ್ಯತೇ ಚಯಃ ಇಮಂ ಧರ್ಮ್ಯಂ ಸಂವಾದಮ್‌ ಆವಯೋಃ |\n\nಜ್ಞಾನ ಯಜ್ಞೇನ ತೇನ ಅಹಮ್‌ ಇಷ್ಟಃ ಸ್ಯಾಮ್‌ ಇತಿ ಮೇ ಮತಿಃ -- ಜೀವನಧರ್ಮವನ್ನರುಹುವ ನಮ್ಮ ಈ\nಮಾತುಕತೆಯನ್ನು ಅಧ್ಯಯನ ಮಾಡಿದರೂ ಕೂಡಾ ಜ್ಞಾನಯಜ್ಞದಿಂದ ನನ್ನನ್ನು ಪೂಜಿಸಿದಂತಾಯಿತು ಎಂದು\nನನ್ನ ಆಶಯ.\n\nಒಂದು ವೇಳೆ ಗೀತೆಯ ಜ್ಞಾನವನ್ನು ಅರಗಿಸಿಕೊಂಡು ಇನ್ನೊಬ್ಬರಿಗೆ ಹೇಳುವ ಕ್ಷಮತೆ ನಮ್ಮಲ್ಲಿಲ್ಲದಿದ್ದರೆ, ಧರ್ಮ\nವಿಷಯಕವಾದ ಈ ಕೃಷ್ಣಾರ್ಜುನ ಸಂವಾದವನ್ನು ಗುರುಮುಖದಲ್ಲಿ ಅಧ್ಯಯನ ಮಾಡಿದರೂ ಕೂಡಾ-ಅದು ಜ್ಞಾನ\nಯಜ್ಞದಂತೆ ಭಗವಂತನ ಪೂಜೆಯಾಗುತ್ತದೆ. “ಇದು ನನ್ನ ಅಭಿಪ್ರಾಯ” ಎಂದು ಹೇಳುತ್ತಾನೆ ಕೃಷ್ಣ. ಭಗವಂತನ\nಬಗೆಗೆ ಮನುಷ್ಯ ಏನೇನು ತಿಳಿದುಕೊಳ್ಳಬೇಕೋ, ಅದನ್ನು ತಿಳಿದು ಹೇಗೆ ಧರ್ಮದ ದಾರಿಯಲ್ಲಿ ಸಾಗಬೇಕು\nಎನ್ನುವ 'ಜೀವನ ಧರ್ಮವನ್ನು' ಗೀತೆಯ ಮೂಲಕ ತಿಳಿದು ಪಾಲಿಸುವವ-ಮೋಕ್ಷವನ್ನು ಸೇರುತ್ತಾನೆ.\n",
  "18.71": "ಶ್ರದ್ಧಾವಾನ್‌ ಅನಸೂಯಃ ಚ ಶೃಣುಯಾತ್‌ ಅಪಿ ಯಃ ನರಃ |\n\nಸಃ ಅಪಿ ಮುಕ್ತಃ ಶುಭಾನ್‌ ಲೋಕಾನ್‌ ಪ್ರಾಪ್ನುಯಾತ್‌ ಪುಣ್ಯಕರ್ಮಣಾಮ್‌ - ನಂಬಿಕೆ ಇರುವ, ಕಿಚ್ಚು ಇರದ\nಮನುಷ್ಯ ಕೇಳಿದರೂ ಸಾಕು. ಅಂತವನೂ ಪಾಪದಿಂದ ಬಿಡುಗಡೆಗೊಂಡು ಪುಣ್ಯಜೀವಿಗಳ ಮಂಗಲಮಯ\nಲೋಕಗಳನ್ನು ಪಡೆದಾನು.\n\nಒಂದು ವೇಳೆ ಗೀತೆಯನ್ನು ಸ್ವಯಂ ಅಧ್ಯಯನ ಮಾಡುವ ಸಾಮರ್ಥ್ಯ ನಮ್ಮಲ್ಲಿ ಇಲ್ಲದೇ ಇದ್ದರೆ, ಯಾವುದೇ\nಅಸೂಯೆ ಇಲ್ಲದೆ, ಶ್ರ ದ್ಧಾಭಕ್ತಿಯಿಂದ ತಿಳಿದವರಿಂದ ಕೇಳಿ ತಿಳಿದುಕೊಂಡರೂ ಸಾಕು- ನಾವು ನಮ್ಮ ಪಾಪವನ್ನು\nತೊಳೆದುಕೊಂಡು ಭಗವಂತನ ಲೋಕವನ್ನು ಸೇರಬಹುದು. ಇದು ಕೃಷ್ಣನ ಭರವಸೆ.",
  "18.72": "ಕಚ್ಚಿತ್‌ ಏತತ್‌ ಶ್ರುತಂ ಪಾರ್ಥ ತ್ವಯಾ ಏಕಾಗ್ರೇಣ ಚೇತಸಾ |\nಕಚ್ಚಿತ್‌ ಅಜ್ಞಾನ ಸಂಮ್ಮೋಹಃ ಪ್ರಣಷ್ಟಃ ತೇ ಧನಂಜಯ - ಪಾರ್ಥಾ, ಇದನ್ನು ಒಮ್ಮನದಿಂದ ಕಿವಿಗೊಟ್ಟು\nಕೇಳಿದೆಯೇನು? ಧನಂಜಯಾ, ನಿನ್ನ ಅಜ್ಞಾನದ ಗೊಂದಲ ಕಳೆಯಿತೇನು?\n\nಇದು ಗೀತೆಯಲ್ಲಿ ಕೃಷ್ಣನ ಕೊನೇಯ ಮಾತು. ಎಲ್ಲವನ್ನು ವಿವರಿಸಿದ ಕೃಷ್ಣ ತನ್ನ ಶಿಷ್ಯ ಅರ್ಜುನನಲ್ಲಿ ಕೇಳುತ್ತಾನೆ:\n“ನಾನು ಹೇಳಿದ್ದು ನಿನ್ನ ಕಿವಿಯೊಳಗೆ ಹೋಗಿ ಹೃದಯಕ್ಕೆ ಮುಟ್ಟಿತೇನೋ? ಇದರಿಂದ ನಿನ್ನ ಮನಸ್ಸಿನಲ್ಲಿದ್ದ\nತಪ್ಪು ತಿಳುವಳಿಕೆ ಗೊಂದಲ ಕಳೆಯಿತೇ?\" ಎಂದು. ಇಲ್ಲಿ ಕೃಷ್ಣ -ಗುರು ತನ್ನ ಶಿಷ್ಯನಲ್ಲಿ ಕೇಳುವಂತೆ\nಅರ್ಜುನನನ್ನು ಪ್ರಶ್ನಿಸಿದ್ದಾನೆ. ಇಲ್ಲಿಗೆ ಗೀತೆಯಲ್ಲಿ ಕೃಷ್ಣನ ನುಡಿಗಳುಳ್ಳ ೫೭೪ ಶ್ಲೋಕಗಳು ಮುಗಿಯಿತು.\nಅರ್ಜುನನ ಒಟ್ಟು ೮೪ ಶ್ಲೋಕಗಳಲ್ಲಿ ಕೊನೇಯ ಶ್ಲೋಕ ಮತ್ತು ಸಂಜಯನ ಒಟ್ಟು ೪೧ ಶ್ಲೋಕಗಳಲ್ಲಿ ಕೊನೇಯ\nಐದು ಶ್ಲೋಕ ಈ ಅಧ್ಯಾಯದ ಉಳಿದ ಭಾಗ. [ಕೃಷ್ಣ-೫೭೪; ಅರ್ಜುನ-೮೪; ಸಂಜಯ-೪೧ ; ಧೃತರಾಷ್ಟ್ರ -೧;\nಒಟ್ಟು ೭೦೦ ಶ್ಲೋಕಗಳು].",
  "18.73": "ಅರ್ಜುನಃ ಉವಾಚ-ಅರ್ಜುನ ಹೇಳಿದನು.\n\nನಷ್ಟಃ ಮೋಹಃ ಸ್ಮೃತಿ ಲಬ್ದಾ ತ್ವತ್‌ ಪ್ರಸಾದಾತ್‌ ಮಯಾ ಅಚ್ಯುತ |\nಸ್ಥಿತಃ ಅಸ್ಮಿ ಗತಸಂದೇಹಃ ಕರಿಷ್ಯೇ ವಚನಂ ತವ -ಅಚ್ಯುತಾ, ಗೊಂದಲ ಕಳೆಯಿತು. ನಿನ್ನ ಹಸಾದದಿಂದ ನನ್ನ\nನೆನಪು ಮರುಕಳಿಸಿತು. ಸಂದೇಹವಳಿದು ಗಟ್ಟಿಯಾಗಿ ನಿಂತಿದ್ದೇನೆ. ನಿನ್ನ ಮಾತಿನಂತೆ ನಡೆಯುತ್ತೇನೆ.\n\nನನ್ನಲ್ಲಿದ್ದ ತಪ್ಪು ತಿಳುವಳಿಕೆ ಕಳೆಯಿತು. ಯಾವುದು ಸರಿ ಯಾವುದು ತಪ್ಪು ಎಂದು ತಿಳಿಯಲಿಕ್ಕಾಗದ ಸ್ಥಿತಿ ನನ್ನಲ್ಲಿತ್ತು- ಅದು ಹೊರಟು ಹೋಯಿತು. ಬಂಧುಮೋಹದಲ್ಲಿ ಹೊರಟುಹೋಗಿದ್ದ ನನ್ನ ಸ್ಮೃತಿ ಮರಳಿ ಬಂತು.\nಅಚ್ಯುತನಾದ ನಿನ್ನ ಅನುಗ್ರಹದಿಂದ ನನ್ನ ಮರೆವು ಮರೆಯಾಯ್ತು. ನನ್ನ ಎಲ್ಲಾ ಪ್ರಶ್ನೆಗಳಿಗೆ ಉತ್ತರ ಸಿಕ್ಕಿದೆ. ನಿನ್ನ\nಮಾತು ಮನವರಿಕೆಯಾಗಿದೆ. ನಿನ್ನ ಮಾತಿನಂತೆಯೇ ನಡೆಯುತ್ತೇನೆ.\n\nಇಲ್ಲಿ ನಾವು ಗಮನಿಸಬೇಕಾದ ಅಂಶವೇನೆಂದರೆ ಅರ್ಜುನ ಕೃಷ್ಣನ ಉಪದೇಶದಿಂದ “ನನಗೆ ಜ್ಞಾನ ಬಂತು'\nಎಂದು ಹೇಳದೇ- ಸ್ಮೃತಿ ಬಂತು ಎಂದಿದ್ದಾನೆ. ಇದರಿಂದ ನಮಗೆ ತಿಳಿವುದೇನೆಂದರೆ- ಅರ್ಜುನ ಆ ಕಾಲದ\nಮಹಾಜ್ಞಾನಿ. ಆದರೆ ಯುದ್ಧರಂಗದಲ್ಲಿ ಆತ ತನ್ನೆಲ್ಲಾ ಸ್ಮೃತಿಯನ್ನು ಕಳೆದುಕೊಂಡು ಕುಸಿದು ಕುಳಿತ. ಇದೊಂದು\nಭಗವಂತನ ಆಟ. ಪ್ರಪಂಚಕ್ಕೆ ಇಂತಹ ಅಮೂಲ್ಯವಾದ ಕೃತಿಯನ್ನು ನೀಡುವುದಕ್ಕೋಸ್ಕರ ಕೃಷ್ಣ ಅರ್ಜುನನನ್ನು\nಈ ರೀತಿ ಮಾಧ್ಯಮವಾಗಿ ಬಳಸಿದ. ಭಗವದ್ಗೀತೆಯಲ್ಲಿ ಏನು ಸಂದೇಶವಿದೆಯೋ ಅದರ ಪ್ರಾಯೋಗಿಕ ವಿವರಣೆ\nಮಹಾಭಾರತ. ಅಲ್ಲಿ ಬರುವ ಒಂದೊಂದು ಪಾತ್ರಗಳೂ ಗೀತೆಯ ಒಂದೊಂದು ಸಂದೇಶವನ್ನು ಪ್ರತಿನಿಧಿಸುತ್ತವೆ.\nಮನಃಶಾಸ್ತ್ರೀಯವಾಗಿ ನೋಡಿದಾಗ ಮಹಾಭಾರತ ಐದು ಸಾವಿರ ವರ್ಷಗಳ ಹಿಂದೆ ಕೌರವ ಪಾಂಡವರ\nನಡುವೆ. ನಡೆದ ಇತಿಹಾಸವಲ್ಲ. ಅದು ನಮ್ಮ ಅಂತರಂಗದ, ನಮ್ಮ ಜೀವನದ ಹೋರಾಟ. ಜ್ಞಾನ\nಸಂದೇಶ(Theory) ಮತ್ತು ಅದರ ಪ್ರಾಯೋಗಿಕ ನಿರೂಪಣೆಯನ್ನು (Practical presentation) ನಮಗೆ\n\nಭಗವಂತ ನೀಡಿರುವುದು ಮಹಾಭಾರತದ ಮೂಲಕ.",
  "18.74": "ಸಂಜಯ ಉವಾಚ-ಸಂಜಯ ಹೇಳಿದನು:\n\nಇತಿ ಅಹಂ ವಾಸುದೇವಸ್ಯ ಪಾರ್ಥಸ್ಯ ಚ ಮಹಾತ್ಮನಃ |\n\nಸಂವಾದಮ್‌ ಇಮಮ್‌ ಅಶ್ರೌಷಮ್‌ ಅದ್ಭುತಂ ರೋಮಹರ್ಷಣಮ್‌ - ಹೀಗೆ ಮಹಾತ್ಮರಾದ ವಾಸುದೇವ ಮತ್ತು\nಪಾರ್ಥರ ಅಚ್ಚರಿಯ ನವಿರೇಳಿಸುವ ಈ ಮಾತುಕತೆಯನ್ನು ನಾನು ಕೇಳಿಸಿಕೊಂಡೆ.\n\nಸಂಜಯ ಕೃಷ್ಣಾರ್ಜುನರ ಈ ಅಪೂರ್ವ ಸಂವಾದವನ್ನು ಸಾಕ್ಷಾತ್‌ ನೋಡಿ ವಿಸ್ಮಯಗೊಂಡ. ಆತ ಹೇಳುತ್ತಾನೆ:\nನನ್ನ ಕಣ್ಮುಂದೆ ನಡೆದ ವಾಸುದೇವ ಮತ್ತು ಅರ್ಜುನರ ಈ ಸಂವಾದವನ್ನು ನಾನು ಕೇಳಿಸಿಕೊಂಡೆ. ಇದು ನನ್ನ\n\nಭಾಗ್ಯ. ನನಗಾದ ಅನುಭವವನ್ನು ಶಬ್ದಗಳಿಂದ ವರ್ಣಿಸಲಾಗದು. ಇದೊಂದು ಅದ್ಭುತ. ಈ ಸಂವಾದವನ್ನು ಕೇಳಿ\nಆನಂದದಿಂದ ಮೈನವಿರೆದ್ದಿದೆ. ಆನಂದದ ಪುಳಕ ನನ್ನನ್ನು ಆವರಿಸಿಕೊಂಡು ಬಿಟ್ಟಿದೆ.\n",
  "18.75": "ವ್ಯಾಸಪ್ರಸಾದಾತ್‌ ಶ್ರುತವಾನ್‌ ಏತತ್‌ ಗುಹ್ಯಮ್‌ ಅಹಂ ಪರಮ್‌ |\n\nಯೋಗಂ ಯೋಗೇಶ್ವರಾತ್‌ ಕೃಷ್ಣಾತ್‌ ಸಾಕ್ಷಾತ್‌ ಕಥಯತಃ ಸ್ವಯಮ್‌ - ವ್ಯಾಸರ ಕರುಣೆಯಿಂದ ನಾನು\nಯೋಗದ ದಾರಿಯನ್ನು, ಈ ಹಿರಿಯ ಗುಟ್ಟನ್ನು ಎಲ್ಲಾ ಯೋಗಮಾರ್ಗಗಳ ಒಡೆಯನಾದ ಕೃಷ್ಣನ\nಬಾಯಿಯಿಂದಲೇ ನೇರವಾಗಿ ಕೇಳಿಸಿಕೊಂಡೆ.\n\nಪರಮ ಪೂಜ್ಯ ಗುರುಗಳಾದ ವ್ಯಾಸರ ಅನುಗ್ರಹದಿಂದ ನಾನು ಈ ಅದ್ಭುತ ಭಾಗ್ಯವನ್ನು ಪಡೆದೆ. ಬೇಕು ಎಂದರೆ\nಸಿಗದ ಪ್ರಪಂಚದ ಅತ್ಯಂತ ರಹಸ್ಯಗಳ ರಹಸ್ಯ ನನಗೂ ತಿಳಿಯಿತು. ಇಡೀ ಜಗತ್ತಿನ ಎಲ್ಲಾ ಶಕ್ತಿಗಳ ಒಂದು\nಸಮಪ್ಪಿರೂಪವಾದ ಯೋಗೇಶ್ವರ ಕೃಷ್ಣನಿಂದ ಅಧ್ಯಾತ್ಮದ ಸಾರ ಸರ್ವಸ್ವವನ್ನು ಸಾಕ್ಷಾತ್‌ ಕೇಳಿಸಿಕೊಂಡೆ.",
  "18.76": "ರಾಜನ್‌ ಸಂಸ್ಕೃತ್ಯಸಂಸ್ಕೃತ್ಯ ಸಂವಾದಮ್‌ ಇಮಮ್‌ ಅದ್ಭುತಮ್‌ |\nಕೇಶವ ಅರ್ಜುನಯೋಃ ಪುಣ್ಯಂ ಹೃಷ್ಯಾಮಿ ಚ ಮುಹುಃಮಹುಃ - ದೊರೆಯೇ, ಕೇಶವಾರ್ಜುನರ ಅಚ್ಚರಿಯ ಈ\nಮೆಚ್ಚಿನ ಮಾತುಕತೆಯನ್ನು ನೆನೆಯುತ್ತಾ ನೆನೆಯುತ್ತಾ ಮತ್ತೆ ಮತ್ತೆ ನವಿರುಗೊಳ್ಳುತ್ತಿದ್ದೇನೆ.\n\nಓ ದೊರೆಯೇ(ಧೃತರಾಷ್ಟ್ರನನ್ನು ಕುರಿತು), ಈ ಅದ್ಭುತ ಸಂವಾದವನ್ನು ನೆನೆ-ನೆನೆದು ವಿಸ್ಮಯ, ಆನಂದ,\nರೋಮಾಂಚನ, ಆಶ್ಚರ್ಯ. ಇಂತದ್ದು ಹಿಂದೆ ಆಗಿಲ್ಲ ಮುಂದೆ ಆಗಲಿಕ್ಕಿಲ್ಲ. ಇಡೀ ವಿಶ್ವವನ್ನು ನಿಯಂತ್ರಿಸುವ,\nಸಮಸ್ತ ದೇವಾಧಿದೇವತೆಗಳನ್ನು ನಿಯಂತ್ರಿಸುವ ಶಕ್ತಿ- ಇಲ್ಲಿ ಅರ್ಜುನನ ಸಾರಥಿ ರೂಪದಲ್ಲಿ ನಿಂತು ನುಡಿದ ಈ\nಅದ್ಭುತ ಸಂದೇಶವನ್ನು- ಹಿಂದೆ ಯಾರೂ ಕೇಳಿದ್ದೂ ಇಲ್ಲ, ಅನುಭವಿಸಿದ್ದೂ ಇಲ್ಲ. ಇದನ್ನು ನೆನಪಿಸಿಕೊಂಡು ಮತ್ತೆ\nಮತ್ತೆ ಪುಳಕಗೊಳ್ಳುತ್ತಿದ್ದೇನೆ.\n",
  "18.77": "ತತ್‌ ಚ ಸಂಸ್ಕೃತ್ಯಸಂಸ್ಕೃತ್ಯ ರೂಪಮ್‌ ಅತ್ಯದ್ಭುತಂ ಹರೇಃ |\nವಿಸ್ಮಯಃ ಮೇ ಮಹಾನ್‌ ರಾಜನ್‌ ಹೃಷ್ಯಾಮಿ ಚ ಪುನಃಪುನಃ -- ದೊರೆಯೇ, ಹರಿಯ ಅಚ್ಚರಿಯ ರೂಪವನ್ನು\nನೆನೆಯುತ್ತಾ ನನಗೆ ಬೆರಗೋ ಬೆರಗು. ಮೈಯಲ್ಲಾ ಮರಳಿಮರಳಿ ನವಿರು.\n\nಕೃಷ್ಣನ ವಿಶ್ವರೂಪ ದರ್ಶನ ಪಡೆದಿದ್ದ ಸಂಜಯ ಮುಂದುವರಿದು ಹೇಳುತ್ತಾನೆ: ಓ ದೊರೆಯೇ, ನಮ್ಮ ಸಮಸ್ತ\nಸಮಸ್ಯೆಗಳನ್ನು ಪರಿಹರಿಸುವ(ಹರಿಃ) ಆ ಪರಮಾತ್ಮ, ಇಂದು ನಮಗೆ ಸಮಸ್ತ ಸಮಸ್ಯೆಯನ್ನೂ ಪರಿಹರಿಸುವ\nಈ ಅದ್ಭುತ ಸಂದೇಶವನ್ನು ಕೊಟ್ಟ. ನಾನು ಕೃಷ್ಣನನ್ನು ಕಂಡೆ; ಅವನ ಅದ್ಭುತ ವಿಶ್ವರೂಪವನ್ನು ಕಂಡೆ; ಅವನ\nಮಾತನ್ನು ಕೇಳಿದೆ; ಇದು ನನ್ನ ಮಾತಿಗೆ ಮೀರಿದ ಸಂತೋಷ. ನಾನು ಖುಷಿಯಿಂದ ತುಂಬಿಹೋಗಿದ್ದೇನೆ.\nಹೀಗೆ ತನ್ನ ಆನಂದವನ್ನು ಹಂಚಿಕೊಂಡ ಸಂಜಯ ಮುಂದೆ ತನಗನಿಸಿದ ಫಲಶ್ರುತಿಯನ್ನು ಹೇಳುತ್ತಾನೆ.\n",
  "18.78": "ಯತ್ರ ಯೋಗೇಶ್ವರಃ ಕೃಷ್ಣಃ ಯತ್ರ ಪಾರ್ಥಃ ಧನುರ್ಧರಃ ।\nತತ್ರ ಶ್ರೀಃ ವಿಜಯಃ ಭೂತಿಃ ಧ್ರುವಾ ನೀತಿಃ ಮತಿಃ ಮಮ -ಯೋಗಮಾರ್ಗಗಳೊಡೆಯನಾದ ಕೃಷ್ಣನಿರುವೆಡೆ,\nಬಿಲ್ಲಾರನಾದ ಪಾರ್ಥನಿರುವೆಡೆ(ನರ-ನಾರಾಯಣನಿರುವೆಡೆ) ಸಿರಿ, ಗೆಲುವು, ಉನ್ನತಿಕೆ ಮತ್ತು ಸ್ಥಿರವಾದ ನೀತಿ\nನೆಲೆಸಿರುತ್ತದೆ ಎಂದು ನನ್ನ ನಿರ್ಧಾರ.\nಎಲ್ಲಿಎಲ್ಲಿ ನರ-ನಾರಾಯಣರಿರುತ್ತಾರೋ ಅಲ್ಲಿ ಎಲ್ಲವೂ ಇದೆ. ಎಲ್ಲಾ ಬಗೆಯ ಸಂಪತ್ತು, ಗೆಲುವು, ಅಂತರಂಗ\nಸಾಧನೆ, ಬಾಹ್ಯ ಉನ್ನತಿ ಎಲ್ಲವೂ ನೆಲೆಸಿರುತ್ತದೆ. ಇದು ನನ್ನ ನಿರ್ಧಾರ ಎನ್ನುತ್ತಾನೆ ಸಂಜಯ.\nಭಗವದ್ಗೀತೆ ನಮಗೆ ಪ್ರಾಪಂಚಿಕ ಸುಖದ ಸೆಳೆತವನ್ನು ಮೀರಿ ಎತ್ತರಕ್ಕೇರಲು ಬೇಕಾದ ಅಧ್ಯಾತ್ಮ ಜ್ಞಾನ ಮತ್ತು\nವೇದ ವಿದ್ಯೆಯನ್ನು ಕೊಡುವ ಅಪೂರ್ವ ಗ್ರಂಥ. ಗೀತೆ ಮನಸ್ಸಿನಲ್ಲಿ ನಿಂತರೆ ಸುಳ್ಳು, ಮೋಸ- ಸಾಧ್ಯವಿಲ್ಲ. ಎಲ್ಲಿ\nಗೀತೆಯ ಅಧ್ಯಯನವಿದೆಯೋ ಅಲ್ಲಿ ಪ್ರಾಮಾಣಿಕತೆ ಇದೆ. ಗೀತೆಯನ್ನು ಓದಿ, ಗೀತೆಯನ್ನು ಮುಟ್ಟಿ ನಾವು ಸುಳ್ಳು\nಹೇಳಿದರೆ, ಅಪ್ರಾಮಾಣಿಕವಾಗಿ ಬದುಕಿದರೆ ಅದು ಆ ಗೀತಾಚಾರ್ಯನಿಗೆ ನಾವು ಮಾಡುವ ದ್ರೋಹ.\nಎಲ್ಲಿ ಗೀತೆಯ ಜ್ಞಾನವಿದೆಯೋ ಅಲ್ಲಿ ಗೆಲುವಿದೆ, ಉನ್ನತಿ ಇದೆ, ನೀತಿ ಇದೆ, ಸಮಪ್ಪಿಯೂ ಇದೆ- ಎನ್ನುವಲ್ಲಿಗೆ\nಭಗವದ್ಗೀತೆಯ ಅತ್ಯದ್ಭುತ ಸಂದೇಶ ಕೊನೆಗೊಂಡಿತು.\nಇತಿ ಅಷ್ಟಾದಶೋಽಧ್ಯಾಯಃ\nಹದಿನೆಂಟನೆಯ ಅಧ್ಯಾಯ ಮುಗಿಯಿತು\n\n| ಸರ್ವೇ ಜನಾಃ ಸುಖಿನೋ ಭವಂತು |\n\n| ಶ್ರೀ ಕೃಷ್ಣಾರ್ಪಣಮಸ್ತು |"
};

if (typeof module !== 'undefined' && module.exports) {
  module.exports = window.BANNANJE_VERSE_MEANINGS;
}
